__d(function(e,a,n,r,i,s,o){i.exports={anagrams:{ru:{about:"\u0412 \u0430\u043d\u0430\u0433\u0440\u0430\u043c\u043c\u0435 \u0432\u0430\u043c \u0434\u0430\u044e\u0442 \u043f\u0435\u0440\u0435\u043c\u0435\u0448\u0430\u043d\u043d\u044b\u0435 \u0431\u0443\u043a\u0432\u044b, \u0430 \u0437\u0430\u0434\u0430\u0447\u0430 \u2014 \u0441\u043e\u0431\u0440\u0430\u0442\u044c \u0438\u0437 \u043d\u0438\u0445 \u043d\u0430\u0441\u0442\u043e\u044f\u0449\u0435\u0435 \u0441\u043b\u043e\u0432\u043e. \u0412\u044b \u0441\u043c\u043e\u0442\u0440\u0438\u0442\u0435 \u043d\u0430 \u0445\u0430\u043e\u0442\u0438\u0447\u043d\u044b\u0439 \u043d\u0430\u0431\u043e\u0440, \u0438\u0449\u0435\u0442\u0435 \u0437\u0430\u043a\u043e\u043d\u043e\u043c\u0435\u0440\u043d\u043e\u0441\u0442\u044c \u0438 \u0432\u0432\u043e\u0434\u0438\u0442\u0435 \u0438\u043b\u0438 \u0432\u044b\u043a\u043b\u0430\u0434\u044b\u0432\u0430\u0435\u0442\u0435 \u0431\u0443\u043a\u0432\u044b \u0432 \u043f\u0440\u0430\u0432\u0438\u043b\u044c\u043d\u043e\u043c \u043f\u043e\u0440\u044f\u0434\u043a\u0435, \u043f\u043e\u043a\u0430 \u043d\u0435 \u0432\u044b\u0448\u043b\u043e \u0432\u0440\u0435\u043c\u044f \u0440\u0430\u0443\u043d\u0434\u0430.",benefit:"\u0422\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442\u0441\u044f \u0432\u0435\u0440\u0431\u0430\u043b\u044c\u043d\u0430\u044f \u0440\u0430\u0431\u043e\u0447\u0430\u044f \u043f\u0430\u043c\u044f\u0442\u044c \u0438 \u0432\u0430\u0448 \u0441\u043b\u043e\u0432\u0430\u0440\u043d\u044b\u0439 \u0437\u0430\u043f\u0430\u0441: \u043d\u0443\u0436\u043d\u043e \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0442\u044c \u0431\u0443\u043a\u0432\u044b \u0432 \u0433\u043e\u043b\u043e\u0432\u0435, \u0442\u0430\u0441\u043e\u0432\u0430\u0442\u044c \u0438\u0445 \u0438 \u0431\u044b\u0441\u0442\u0440\u043e \u043f\u0435\u0440\u0435\u0431\u0438\u0440\u0430\u0442\u044c \u0441\u043b\u043e\u0432\u0430, \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u043f\u043e\u0434\u043e\u0439\u0434\u0443\u0442. \u0417\u0430\u043e\u0434\u043d\u043e \u0440\u0430\u0437\u0432\u0438\u0432\u0430\u0435\u0442\u0441\u044f \u0433\u0438\u0431\u043a\u043e\u0441\u0442\u044c \u043c\u044b\u0448\u043b\u0435\u043d\u0438\u044f \u2014 \u043e\u0447\u0435\u0432\u0438\u0434\u043d\u0430\u044f \u0440\u0430\u0441\u043a\u043b\u0430\u0434\u043a\u0430 \u043f\u043e\u0447\u0442\u0438 \u0432\u0441\u0435\u0433\u0434\u0430 \u043e\u043a\u0430\u0437\u044b\u0432\u0430\u0435\u0442\u0441\u044f \u0442\u0443\u043f\u0438\u043a\u043e\u043c, \u0438 \u043f\u0440\u0438\u0445\u043e\u0434\u0438\u0442\u0441\u044f \u043b\u043e\u043c\u0430\u0442\u044c \u043f\u0435\u0440\u0432\u0443\u044e \u0434\u043e\u0433\u0430\u0434\u043a\u0443.",history:"\u041f\u0435\u0440\u0435\u0441\u0442\u0430\u043d\u043e\u0432\u043a\u0430 \u0431\u0443\u043a\u0432 \u0443\u0445\u043e\u0434\u0438\u0442 \u043a \u0434\u0440\u0435\u0432\u043d\u0438\u043c \u0433\u0440\u0435\u043a\u0430\u043c, \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u0442\u0430\u043a \u0438\u0441\u043a\u0430\u043b\u0438 \u0432 \u0438\u043c\u0435\u043d\u0430\u0445 \u0441\u043a\u0440\u044b\u0442\u044b\u0439 \u0441\u043c\u044b\u0441\u043b; \u043f\u0440\u0438\u0451\u043c \u0432\u0441\u0442\u0440\u0435\u0447\u0430\u0435\u0442\u0441\u044f \u0432 \u0442\u0430\u043b\u043c\u0443\u0434\u0438\u0447\u0435\u0441\u043a\u043e\u0439, \u043c\u0438\u0434\u0440\u0430\u0448\u0438\u0441\u0442\u0441\u043a\u043e\u0439 \u0438 \u043a\u0430\u0431\u0431\u0430\u043b\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043a\u043e\u0439 \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u0438 (\u0435\u0433\u043e \u043d\u0430\u0437\u044b\u0432\u0430\u043b\u0438 \u0442\u0435\u043c\u0443\u0440\u0430). \u0410\u043d\u0430\u0433\u0440\u0430\u043c\u043c\u044b \u0431\u044b\u043b\u0438 \u0432 \u0445\u043e\u0434\u0443 \u043f\u043e \u0432\u0441\u0435\u0439 \u0441\u0440\u0435\u0434\u043d\u0435\u0432\u0435\u043a\u043e\u0432\u043e\u0439 \u0438 \u0440\u0430\u043d\u043d\u0435\u043d\u043e\u0432\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u043e\u0439 \u0415\u0432\u0440\u043e\u043f\u0435, \u0446\u0435\u043d\u0438\u043b\u0438\u0441\u044c \u043a\u0430\u043a \u043e\u0441\u0442\u0440\u043e\u0443\u043c\u043d\u0430\u044f \u0438\u0433\u0440\u0430 \u0441\u043b\u043e\u0432 \u043d\u0430 \u043b\u0430\u0442\u044b\u043d\u0438 \u0438 \u0434\u0430\u0436\u0435 \u043e\u0431\u0437\u0430\u0432\u0435\u043b\u0438\u0441\u044c \u043f\u0440\u0430\u0432\u0438\u043b\u0430\u043c\u0438 \u2014 \u043d\u0430\u043f\u0440\u0438\u043c\u0435\u0440, \u0443 \u0414\u0436\u043e\u0440\u0434\u0436\u0430 \u041f\u0443\u0442\u0442\u0435\u043d\u0445\u044d\u043c\u0430 \u0432 1589 \u0433\u043e\u0434\u0443.",creator:"\u0415\u0434\u0438\u043d\u043e\u0433\u043e \u0438\u0437\u043e\u0431\u0440\u0435\u0442\u0430\u0442\u0435\u043b\u044f \u043d\u0435\u0442. \u0410\u043d\u0430\u0433\u0440\u0430\u043c\u043c\u0430 \u2014 \u044d\u0442\u043e \u043d\u0430\u0440\u043e\u0434\u043d\u0430\u044f \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u044f \u0438\u0433\u0440\u044b \u0441\u043e \u0441\u043b\u043e\u0432\u043e\u043c, \u0443\u0445\u043e\u0434\u044f\u0449\u0430\u044f \u043a\u043e\u0440\u043d\u044f\u043c\u0438 \u0432 \u0414\u0440\u0435\u0432\u043d\u044e\u044e \u0413\u0440\u0435\u0446\u0438\u044e; \u0435\u0451 \u0447\u0430\u0441\u0442\u043e \u0441\u0432\u044f\u0437\u044b\u0432\u0430\u044e\u0442 \u0441 \u043f\u043e\u044d\u0442\u043e\u043c \u041b\u0438\u043a\u043e\u0444\u0440\u043e\u043d\u043e\u043c (III \u0432\u0435\u043a \u0434\u043e \u043d. \u044d.), \u0445\u043e\u0442\u044f \u044d\u0442\u043e \u043f\u0440\u0438\u043f\u0438\u0441\u044b\u0432\u0430\u043d\u0438\u0435 \u043e\u043f\u0438\u0440\u0430\u0435\u0442\u0441\u044f \u043d\u0430 \u0433\u043e\u0440\u0430\u0437\u0434\u043e \u0431\u043e\u043b\u0435\u0435 \u043f\u043e\u0437\u0434\u043d\u0438\u0439 \u043f\u0435\u0440\u0435\u0441\u043a\u0430\u0437 \u0418\u043e\u0430\u043d\u043d\u0430 \u0426\u0435\u0446\u0430 \u0432 XII \u0432\u0435\u043a\u0435. \u041a XVII \u0432\u0435\u043a\u0443 \u0437\u0430\u0431\u0430\u0432\u0430 \u0431\u044b\u043b\u0430 \u0442\u0430\u043a \u043f\u043e\u043f\u0443\u043b\u044f\u0440\u043d\u0430, \u0447\u0442\u043e \u0444\u0440\u0430\u043d\u0446\u0443\u0437\u0441\u043a\u0438\u0439 \u043a\u043e\u0440\u043e\u043b\u044c \u041b\u044e\u0434\u043e\u0432\u0438\u043a XIII \u0434\u0435\u0440\u0436\u0430\u043b \u0422\u043e\u043c\u0430 \u0411\u0438\u0439\u043e\u043d\u0430 \u043f\u0440\u0438\u0434\u0432\u043e\u0440\u043d\u044b\u043c \u0430\u043d\u0430\u0433\u0440\u0430\u043c\u043c\u0430\u0442\u0438\u0441\u0442\u043e\u043c \u043d\u0430 \u0436\u0430\u043b\u043e\u0432\u0430\u043d\u044c\u0435.",methods:"\u0421\u043d\u0430\u0447\u0430\u043b\u0430 \u0438\u0449\u0438\u0442\u0435 \u0447\u0430\u0441\u0442\u044b\u0435 \u043e\u043a\u043e\u043d\u0447\u0430\u043d\u0438\u044f \u0438 \u043f\u0440\u0438\u0441\u0442\u0430\u0432\u043a\u0438 \u0438 \u0434\u043e\u0441\u0442\u0440\u0430\u0438\u0432\u0430\u0439\u0442\u0435 \u0441\u043b\u043e\u0432\u043e \u0432\u043e\u043a\u0440\u0443\u0433 \u043d\u0438\u0445. \u041e\u0442\u0434\u0435\u043b\u044c\u043d\u043e \u0432\u044b\u043f\u0438\u0448\u0438\u0442\u0435 \u0433\u043b\u0430\u0441\u043d\u044b\u0435 \u0438 \u0441\u043e\u0433\u043b\u0430\u0441\u043d\u044b\u0435, \u0447\u0442\u043e\u0431\u044b \u0443\u0432\u0438\u0434\u0435\u0442\u044c \xab\u0441\u044b\u0440\u044c\u0451\xbb, \u0432\u044b\u0441\u043c\u0430\u0442\u0440\u0438\u0432\u0430\u0439\u0442\u0435 \u0443\u0441\u0442\u043e\u0439\u0447\u0438\u0432\u044b\u0435 \u0441\u043e\u0447\u0435\u0442\u0430\u043d\u0438\u044f \u0431\u0443\u043a\u0432 \u0438 \u0440\u0435\u0430\u043b\u044c\u043d\u043e \u043f\u0435\u0440\u0435\u0442\u0430\u0441\u043e\u0432\u044b\u0432\u0430\u0439\u0442\u0435 \u0444\u0438\u0448\u043a\u0438, \u0430 \u043d\u0435 \u0432\u0433\u043b\u044f\u0434\u044b\u0432\u0430\u0439\u0442\u0435\u0441\u044c \u0432 \u043d\u0438\u0445 \u2014 \u0434\u0432\u0438\u0436\u0435\u043d\u0438\u0435 \u0431\u0443\u043a\u0432 \u0447\u0430\u0441\u0442\u043e \u0441\u0430\u043c\u043e \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u044b\u0432\u0430\u0435\u0442 \u043e\u0442\u0432\u0435\u0442. \u0415\u0441\u043b\u0438 \u0437\u0430\u0441\u0442\u0440\u044f\u043b\u0438 \u043d\u0430 \u043e\u0434\u043d\u043e\u0439 \u0440\u0430\u0441\u043a\u043b\u0430\u0434\u043a\u0435, \u043e\u0441\u043e\u0437\u043d\u0430\u043d\u043d\u043e \u0431\u0440\u043e\u0441\u044c\u0442\u0435 \u0435\u0451: \u0438\u043c\u0435\u043d\u043d\u043e \u043f\u0435\u0440\u0432\u0430\u044f \u043d\u0430\u0432\u044f\u0437\u0447\u0438\u0432\u0430\u044f \u0432\u0435\u0440\u0441\u0438\u044f \u043e\u0431\u044b\u0447\u043d\u043e \u0438 \u043c\u0435\u0448\u0430\u0435\u0442.",duration:"\u041a\u043e\u0440\u043e\u0442\u043a\u0438\u0435 \u0447\u0430\u0441\u0442\u044b\u0435 \u043f\u043e\u0434\u0445\u043e\u0434\u044b \u043b\u0443\u0447\u0448\u0435 \u043c\u0430\u0440\u0430\u0444\u043e\u043d\u043e\u0432: 5\u201310 \u043c\u0438\u043d\u0443\u0442 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0440\u0430\u0437 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e \u0434\u043e\u0441\u0442\u0430\u0442\u043e\u0447\u043d\u043e. \u041e\u0441\u0442\u0430\u043d\u0430\u0432\u043b\u0438\u0432\u0430\u0439\u0442\u0435\u0441\u044c, \u043a\u0430\u043a \u0442\u043e\u043b\u044c\u043a\u043e \u043d\u0430\u0447\u0438\u043d\u0430\u0435\u0442\u0435 \u0431\u0443\u043a\u0441\u043e\u0432\u0430\u0442\u044c \u2014 \u043e\u0442 \u0443\u0441\u0442\u0430\u043b\u043e\u0441\u0442\u0438 \u043f\u0435\u0440\u0435\u0431\u043e\u0440 \u0441\u043b\u043e\u0432 \u0438\u0434\u0451\u0442 \u043c\u0435\u0434\u043b\u0435\u043d\u043d\u0435\u0435, \u0430 \u043d\u0435 \u043e\u0441\u0442\u0440\u0435\u0435.",research:"\u041d\u0430\u0434\u0451\u0436\u043d\u0435\u0435 \u0432\u0441\u0435\u0433\u043e \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u0435\u0442\u0441\u044f \u043e\u0447\u0435\u0432\u0438\u0434\u043d\u043e\u0435: \u0432\u044b \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u0438 \u0442\u043e\u0447\u043d\u0435\u0435 \u0440\u0430\u0437\u0433\u0430\u0434\u044b\u0432\u0430\u0435\u0442\u0435 \u0430\u043d\u0430\u0433\u0440\u0430\u043c\u043c\u044b \u0438 \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u0432\u044b\u0442\u0430\u0441\u043a\u0438\u0432\u0430\u0435\u0442\u0435 \u0441\u043b\u043e\u0432\u0430 \u0438\u0437 \u043f\u0430\u043c\u044f\u0442\u0438. \u0411\u043e\u043b\u0435\u0435 \u0448\u0438\u0440\u043e\u043a\u0438\u0435 \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f \u043a\u0443\u0434\u0430 \u0441\u043b\u0430\u0431\u0435\u0435 \u2014 \u043d\u0435\u0442 \u0443\u0431\u0435\u0434\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0445 \u0434\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432, \u0447\u0442\u043e \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0430 \u0430\u043d\u0430\u0433\u0440\u0430\u043c\u043c \u043f\u043e\u0432\u044b\u0448\u0430\u0435\u0442 \u043e\u0431\u0449\u0438\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0438\u043b\u0438 \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0438\u0442\u0441\u044f \u043d\u0430 \u043d\u0435 \u0441\u0432\u044f\u0437\u0430\u043d\u043d\u044b\u0435 \u043d\u0430\u0432\u044b\u043a\u0438, \u0430 \u0438\u0437\u0432\u0435\u0441\u0442\u043d\u044b\u0435 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u044f \u043e \u0441\u0432\u044f\u0437\u0438 \u0441\u043b\u043e\u0432\u0435\u0441\u043d\u044b\u0445 \u0433\u043e\u043b\u043e\u0432\u043e\u043b\u043e\u043c\u043e\u043a \u0441 \u043e\u0442\u0441\u0440\u043e\u0447\u043a\u043e\u0439 \u0443\u0445\u0443\u0434\u0448\u0435\u043d\u0438\u044f \u043f\u0430\u043c\u044f\u0442\u0438 \u043d\u0430\u0431\u043b\u044e\u0434\u0430\u0442\u0435\u043b\u044c\u043d\u044b\u0435, \u0442\u043e \u0435\u0441\u0442\u044c \u043f\u043e\u043a\u0430\u0437\u044b\u0432\u0430\u044e\u0442 \u0441\u043e\u0432\u043f\u0430\u0434\u0435\u043d\u0438\u0435, \u0430 \u043d\u0435 \u043f\u0440\u0438\u0447\u0438\u043d\u0443. \u041a \u0433\u0440\u043e\u043c\u043a\u0438\u043c \u0437\u0430\u044f\u0432\u043b\u0435\u043d\u0438\u044f\u043c \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u0435\u0441\u044c \u0441\u043f\u043e\u043a\u043e\u0439\u043d\u043e \u0438 \u0446\u0435\u043d\u0438\u0442\u0435 \u0437\u0430\u043d\u044f\u0442\u0438\u0435 \u0437\u0430 \u0442\u043e, \u0447\u0442\u043e \u043e\u043d\u043e \u0440\u0435\u0430\u043b\u044c\u043d\u043e \u0434\u0430\u0451\u0442.",rec:"\u0420\u0430\u0437\u0433\u0430\u0434\u044b\u0432\u0430\u0439\u0442\u0435 \u043f\u043e \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0441\u043b\u043e\u0432 \u0432 \u0434\u0435\u043d\u044c \u0440\u0430\u0434\u0438 \u0440\u0430\u0437\u043c\u0438\u043d\u043a\u0438 \u0441\u043b\u043e\u0432\u0430\u0440\u043d\u043e\u0433\u043e \u0437\u0430\u043f\u0430\u0441\u0430 \u0438 \u043f\u0440\u0438\u044f\u0442\u043d\u043e\u0433\u043e \u0449\u0435\u043b\u0447\u043a\u0430 \u0434\u043e\u0433\u0430\u0434\u043a\u0438, \u043d\u043e \u043d\u0435 \u0436\u0434\u0438\u0442\u0435, \u0447\u0442\u043e \u044d\u0442\u043e \u0441\u0434\u0435\u043b\u0430\u0435\u0442 \u0432\u0430\u0441 \u0443\u043c\u043d\u0435\u0435 \u0432\u043e\u043e\u0431\u0449\u0435.",faq:[["\u0421\u0442\u0430\u043d\u0443 \u043b\u0438 \u044f \u0443\u043c\u043d\u0435\u0435 \u0432 \u0446\u0435\u043b\u043e\u043c, \u0440\u0430\u0437\u0433\u0430\u0434\u044b\u0432\u0430\u044f \u0430\u043d\u0430\u0433\u0440\u0430\u043c\u043c\u044b?","\u041f\u043e-\u0447\u0435\u0441\u0442\u043d\u043e\u043c\u0443 \u2014 \u043d\u0435\u0442. \u0412\u044b \u0437\u0430\u043c\u0435\u0442\u043d\u043e \u043f\u0440\u0438\u0431\u0430\u0432\u0438\u0442\u0435 \u0432 \u0441\u0430\u043c\u0438\u0445 \u0430\u043d\u0430\u0433\u0440\u0430\u043c\u043c\u0430\u0445 \u0438 \u0432 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u0438 \u0432\u0441\u043f\u043e\u043c\u0438\u043d\u0430\u043d\u0438\u044f \u0441\u043b\u043e\u0432, \u043d\u043e \u0442\u0432\u0451\u0440\u0434\u044b\u0445 \u0434\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432, \u0447\u0442\u043e \u043d\u0430\u0432\u044b\u043a \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0438\u0442\u0441\u044f \u043d\u0430 \u043e\u0431\u0449\u0438\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0438\u043b\u0438 \u0434\u0440\u0443\u0433\u0438\u0435 \u0437\u0430\u0434\u0430\u0447\u0438, \u043d\u0435\u0442."],["\u042d\u0442\u043e \u043f\u0440\u0430\u0432\u0434\u0430 \u043f\u043e\u043c\u043e\u0433\u0430\u0435\u0442 \u0441\u043b\u043e\u0432\u0430\u0440\u043d\u043e\u043c\u0443 \u0437\u0430\u043f\u0430\u0441\u0443?","\u042d\u0442\u043e \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u0442\u043e\u0442 \u0437\u0430\u043f\u0430\u0441, \u0447\u0442\u043e \u0443\u0436\u0435 \u0435\u0441\u0442\u044c, \u0437\u0430\u0441\u0442\u0430\u0432\u043b\u044f\u044f \u0431\u044b\u0441\u0442\u0440\u043e \u0435\u0433\u043e \u0434\u043e\u0441\u0442\u0430\u0432\u0430\u0442\u044c; \u0434\u043b\u0438\u043d\u043d\u044b\u0435 \u0438\u043b\u0438 \u0442\u0435\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u0438\u0435 \u043d\u0430\u0431\u043e\u0440\u044b \u043c\u043e\u0433\u0443\u0442 \u043f\u043e\u0437\u043d\u0430\u043a\u043e\u043c\u0438\u0442\u044c \u0441 \u043d\u043e\u0432\u044b\u043c\u0438 \u0441\u043b\u043e\u0432\u0430\u043c\u0438, \u043d\u043e \u044d\u0442\u043e \u0441\u043a\u043e\u0440\u0435\u0435 \u0437\u0430\u0442\u043e\u0447\u043a\u0430 \u043d\u0430\u0432\u044b\u043a\u0430, \u0447\u0435\u043c \u0441\u043f\u043e\u0441\u043e\u0431 \u0432\u044b\u0443\u0447\u0438\u0442\u044c \u043c\u043d\u043e\u0433\u043e \u0441\u043b\u043e\u0432 \u0441 \u043d\u0443\u043b\u044f."],["\u0417\u0430\u043b\u0438\u043f\u0430\u044e \u043d\u0430 \u043e\u0434\u043d\u043e\u0439 \u043d\u0435\u0432\u0435\u0440\u043d\u043e\u0439 \u0440\u0430\u0441\u043a\u043b\u0430\u0434\u043a\u0435. \u0427\u0442\u043e \u0434\u0435\u043b\u0430\u0442\u044c?","\u0414\u0440\u043e\u0431\u0438\u0442\u0435 \u0431\u0443\u043a\u0432\u044b: \u043e\u0442\u0434\u0435\u043b\u0438\u0442\u0435 \u0433\u043b\u0430\u0441\u043d\u044b\u0435 \u043e\u0442 \u0441\u043e\u0433\u043b\u0430\u0441\u043d\u044b\u0445, \u0438\u0449\u0438\u0442\u0435 \u0437\u043d\u0430\u043a\u043e\u043c\u044b\u0435 \u043e\u043a\u043e\u043d\u0447\u0430\u043d\u0438\u044f \u0438 \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043a\u0438 \u043f\u0435\u0440\u0435\u0442\u0430\u0441\u043e\u0432\u044b\u0432\u0430\u0439\u0442\u0435 \u0444\u0438\u0448\u043a\u0438, \u0430 \u043d\u0435 \u0443\u043f\u0438\u0440\u0430\u0439\u0442\u0435\u0441\u044c \u0432\u0437\u0433\u043b\u044f\u0434\u043e\u043c. \u041e\u0442\u043a\u0430\u0437 \u043e\u0442 \u043f\u0435\u0440\u0432\u043e\u0439 \u0434\u043e\u0433\u0430\u0434\u043a\u0438 \u043e\u0431\u044b\u0447\u043d\u043e \u0438 \u0435\u0441\u0442\u044c \u0442\u043e\u0442 \u0445\u043e\u0434, \u0447\u0442\u043e \u0432\u0441\u0451 \u0440\u0430\u0437\u0431\u043b\u043e\u043a\u0438\u0440\u0443\u0435\u0442."]],variants:"\u0418\u0437 \u0440\u0430\u0441\u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0451\u043d\u043d\u044b\u0445 \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u043e\u0432: \u0441\u043b\u043e\u0432\u0430 \u0444\u0438\u043a\u0441\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u043e\u0439 \u0434\u043b\u0438\u043d\u044b, \u0440\u0430\u0443\u043d\u0434\u044b \u043d\u0430 \u0432\u0440\u0435\u043c\u044f, \u0442\u0435\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u0438\u0435 \u043d\u0430\u0431\u043e\u0440\u044b \u0431\u0443\u043a\u0432, \u0441\u0431\u043e\u0440\u043a\u0430 \u043a\u0430\u043a \u043c\u043e\u0436\u043d\u043e \u0431\u043e\u043b\u044c\u0448\u0435\u0433\u043e \u0447\u0438\u0441\u043b\u0430 \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u0445 \u0441\u043b\u043e\u0432 \u0438\u0437 \u043e\u0434\u043d\u043e\u0433\u043e \u0434\u043b\u0438\u043d\u043d\u043e\u0433\u043e \u0438 \u043d\u0430\u0440\u0430\u0441\u0442\u0430\u044e\u0449\u0430\u044f \u0441\u043b\u043e\u0436\u043d\u043e\u0441\u0442\u044c, \u043a\u043e\u0433\u0434\u0430 \u0441\u043b\u043e\u0432\u0430 \u0443\u0434\u043b\u0438\u043d\u044f\u044e\u0442\u0441\u044f \u043f\u043e \u043c\u0435\u0440\u0435 \u043f\u0440\u043e\u0445\u043e\u0436\u0434\u0435\u043d\u0438\u044f."},en:{about:"An anagram puzzle gives you a scrambled set of letters, and your job is to rearrange them into a real word. You read the jumble, search for a pattern, and type or tap the letters back in the right order before the round ends.",benefit:"It works your verbal working memory and your mental lexicon: you have to hold the letters in mind, juggle them, and rapidly probe your vocabulary for a word that fits. It also trains flexible, set-breaking thinking, since the obvious arrangement is usually a dead end.",history:"Letter rearrangement goes back to the ancient Greeks, who used it to tease hidden meanings out of names, and it appears in Talmudic, Midrashic and Kabbalist writing (the technique called temurah). Anagrams were popular across medieval and early-modern Europe, were prized as clever wordplay in Latin, and even acquired formal rules, such as George Puttenham's in 1589.",creator:"There is no single inventor. The anagram is a folk wordplay tradition with Greek roots, often linked to the poet Lycophron in the 3rd century BCE, though that attribution rests on a much later 12th-century account by John Tzetzes. By the 17th century it was popular enough that King Louis XIII kept Thomas Billon as a paid Royal Anagrammatist.",methods:"Scan for common endings (-ING, -ED, -TION) and prefixes first, then build the rest around them. Pull out the vowels and consonants separately to see the raw material, look for likely letter pairs (TH, CH, ST), and physically shuffle the tiles rather than staring, since moving the letters often triggers the solution. If you get stuck on one arrangement, deliberately abandon it, that fixed first guess is usually what is blocking you.",duration:"Short, frequent sessions beat marathons: 5 to 10 minutes a few times a week is plenty. Stop when you notice yourself stalling, fatigue makes the word search slower, not sharper.",research:"Evidence is strongest for the obvious thing, you get faster and more accurate at solving anagrams and at retrieving words. The wider promises are far shakier: there is no convincing proof that anagram practice raises general intelligence or transfers to unrelated skills, and the well-known studies linking word puzzles to delayed memory decline are observational, so they show association, not that the puzzles caused it. Treat the grand claims with caution and enjoy it for what it reliably is.",rec:"Solve a few words daily for the vocabulary workout and the satisfying click of insight, but do not expect it to make you smarter in general.",faq:[["Will solving anagrams make me smarter overall?","Realistically, no. You will get noticeably better at anagrams and at calling words to mind, but there is no solid evidence that the skill spreads to general intelligence or unrelated mental tasks."],["Does it actually help my vocabulary?","It exercises the vocabulary you already have by forcing fast retrieval, and longer or themed sets can expose you to new words, but it is a sharpening drill more than a way to learn many words from scratch."],["I get stuck staring at the same wrong arrangement. What helps?","Break up the letters: separate vowels from consonants, look for familiar endings, and physically reshuffle the tiles instead of fixating. Letting go of your first guess is usually the move that unlocks it."]],variants:"Common variations include fixed-length jumbles, timed rounds against the clock, themed letter sets, building as many smaller words as possible from one long word, and progressive difficulty where the words lengthen as you advance."},es:{about:"Un juego de anagramas te entrega un conjunto de letras desordenadas y tu tarea es reordenarlas para formar una palabra real. Lees la mara\xf1a de letras, buscas un patr\xf3n y escribes o tocas las letras en el orden correcto antes de que termine la ronda.",benefit:"Pone a trabajar tu memoria de trabajo verbal y tu l\xe9xico mental: tienes que retener las letras en la mente, hacer malabares con ellas y sondear con rapidez tu vocabulario en busca de una palabra que encaje. Tambi\xe9n entrena el pensamiento flexible capaz de romper esquemas, ya que la disposici\xf3n m\xe1s obvia suele ser un callej\xf3n sin salida.",history:"Reordenar letras se remonta a los antiguos griegos, que lo usaban para extraer significados ocultos de los nombres, y aparece en los escritos talm\xfadicos, midr\xe1sicos y cabal\xedsticos (la t\xe9cnica llamada temur\xe1). Los anagramas fueron populares en toda la Europa medieval y moderna temprana, se valoraban como un ingenioso juego de palabras en lat\xedn e incluso adquirieron reglas formales, como las de George Puttenham en 1589.",creator:"No hay un \xfanico inventor. El anagrama es una tradici\xf3n popular de juego de palabras de ra\xedces griegas, a menudo vinculada al poeta Licofr\xf3n en el siglo III a. C., aunque esa atribuci\xf3n se apoya en un relato muy posterior del siglo XII escrito por Juan Tzetzes. Para el siglo XVII era lo bastante popular como para que el rey Luis XIII mantuviera a Thomas Billon como Anagramatista Real a sueldo.",methods:"Busca primero las terminaciones comunes (-ING, -ED, -TION) y los prefijos, y construye el resto en torno a ellos. Separa las vocales de las consonantes para ver la materia prima, busca pares de letras probables (TH, CH, ST) y mueve f\xedsicamente las fichas en lugar de quedarte mirando, ya que desplazar las letras a menudo desencadena la soluci\xf3n. Si te atascas en una disposici\xf3n, aband\xf3nala a prop\xf3sito: esa primera suposici\xf3n fija suele ser justo lo que te bloquea.",duration:"Las sesiones cortas y frecuentes superan a las maratones: de 5 a 10 minutos unas cuantas veces por semana es suficiente. Detente cuando notes que te estancas, porque el cansancio vuelve la b\xfasqueda de palabras m\xe1s lenta, no m\xe1s afilada.",research:"La evidencia es m\xe1s s\xf3lida para lo evidente: te vuelves m\xe1s r\xe1pido y m\xe1s preciso resolviendo anagramas y recuperando palabras. Las promesas m\xe1s amplias son mucho m\xe1s endebles: no hay pruebas convincentes de que practicar anagramas eleve la inteligencia general ni se transfiera a habilidades no relacionadas, y los conocidos estudios que vinculan los juegos de palabras con un deterioro de memoria m\xe1s tard\xedo son observacionales, de modo que muestran asociaci\xf3n, no que los juegos lo hayan causado. Toma las grandes afirmaciones con cautela y disfr\xfatalo por lo que de forma fiable es.",rec:"Resuelve unas cuantas palabras a diario por el ejercicio de vocabulario y por ese satisfactorio chasquido de comprensi\xf3n, pero no esperes que te haga m\xe1s inteligente en general.",faq:[["\xbfResolver anagramas me har\xe1 m\xe1s inteligente en general?","Siendo realistas, no. Mejorar\xe1s notablemente en anagramas y en traer palabras a la mente, pero no hay evidencia s\xf3lida de que la habilidad se extienda a la inteligencia general ni a otras tareas mentales no relacionadas."],["\xbfAyuda de verdad a mi vocabulario?","Ejercita el vocabulario que ya tienes al forzar una recuperaci\xf3n r\xe1pida, y los conjuntos m\xe1s largos o tem\xe1ticos pueden exponerte a palabras nuevas, pero es m\xe1s un ejercicio de afilado que una forma de aprender muchas palabras desde cero."],["Me quedo atascado mirando la misma disposici\xf3n equivocada. \xbfQu\xe9 ayuda?","Descomp\xf3n las letras: separa las vocales de las consonantes, busca terminaciones familiares y reordena f\xedsicamente las fichas en lugar de obsesionarte. Soltar tu primera suposici\xf3n suele ser el movimiento que lo desbloquea."]],variants:"Entre las variantes habituales est\xe1n las mara\xf1as de longitud fija, las rondas contrarreloj, los conjuntos de letras tem\xe1ticos, formar tantas palabras peque\xf1as como sea posible a partir de una palabra larga, y la dificultad progresiva en la que las palabras se alargan a medida que avanzas."},de:{about:"Ein Anagramm-R\xe4tsel gibt dir eine durcheinandergew\xfcrfelte Buchstabenmenge, und deine Aufgabe ist es, daraus ein echtes Wort zu bilden. Du liest das Buchstabengewirr, suchst nach einem Muster und tippst oder klickst die Buchstaben in der richtigen Reihenfolge ein, bevor die Runde endet.",benefit:"Es fordert dein verbales Arbeitsged\xe4chtnis und deinen mentalen Wortschatz: Du musst die Buchstaben im Kopf behalten, sie hin- und herschieben und blitzschnell deinen Wortschatz nach einem passenden Wort durchsuchen. Au\xdferdem trainiert es flexibles, eingefahrene Muster durchbrechendes Denken, denn die naheliegende Anordnung f\xfchrt meist in eine Sackgasse.",history:"Das Umstellen von Buchstaben reicht bis zu den alten Griechen zur\xfcck, die damit verborgene Bedeutungen aus Namen herauskitzelten, und es taucht in talmudischen, midraschischen und kabbalistischen Schriften auf (die Technik namens Temurah). Anagramme waren im mittelalterlichen und fr\xfchneuzeitlichen Europa beliebt, galten im Lateinischen als kunstvolles Wortspiel und erhielten sogar formale Regeln, etwa die von George Puttenham im Jahr 1589.",creator:"Es gibt keinen einzelnen Erfinder. Das Anagramm ist eine volkst\xfcmliche Wortspiel-Tradition mit griechischen Wurzeln, oft mit dem Dichter Lykophron im 3. Jahrhundert v. Chr. in Verbindung gebracht, auch wenn diese Zuschreibung auf einem viel sp\xe4teren Bericht von Johannes Tzetzes aus dem 12. Jahrhundert beruht. Im 17. Jahrhundert war es so beliebt, dass K\xf6nig Ludwig XIII. Thomas Billon als bezahlten k\xf6niglichen Anagrammatisten besch\xe4ftigte.",methods:"Halte zuerst nach g\xe4ngigen Endungen (-UNG, -ENT, -ION) und Vorsilben Ausschau und baue den Rest darum herum auf. Trenne Vokale und Konsonanten getrennt heraus, um das Rohmaterial zu sehen, achte auf wahrscheinliche Buchstabenpaare (CH, ST, SCH) und schiebe die Kacheln tats\xe4chlich umher, statt nur zu starren, denn das Bewegen der Buchstaben l\xf6st die L\xf6sung oft erst aus. Wenn du an einer Anordnung festh\xe4ngst, verwirf sie bewusst, denn genau diese fixierte erste Vermutung blockiert dich meist.",duration:"Kurze, h\xe4ufige Einheiten schlagen Marathonsitzungen: 5 bis 10 Minuten ein paar Mal pro Woche reichen v\xf6llig. H\xf6r auf, sobald du merkst, dass du ins Stocken ger\xe4tst, denn M\xfcdigkeit macht die Wortsuche langsamer, nicht sch\xe4rfer.",research:"Die Belege sind f\xfcr das Naheliegende am st\xe4rksten: Du wirst schneller und genauer beim L\xf6sen von Anagrammen und beim Abrufen von W\xf6rtern. Die weitreichenderen Versprechen sind weit wackeliger: Es gibt keinen \xfcberzeugenden Beleg daf\xfcr, dass Anagramm-\xdcbung die allgemeine Intelligenz steigert oder auf andere F\xe4higkeiten \xfcbertr\xe4gt, und die bekannten Studien, die Wortr\xe4tsel mit verz\xf6gertem Ged\xe4chtnisabbau verkn\xfcpfen, sind Beobachtungsstudien und zeigen daher einen Zusammenhang, nicht dass die R\xe4tsel die Ursache w\xe4ren. Begegne den gro\xdfen Behauptungen mit Vorsicht und genie\xdfe es f\xfcr das, was es zuverl\xe4ssig ist.",rec:"L\xf6se t\xe4glich ein paar W\xf6rter f\xfcr das Vokabeltraining und das befriedigende Klicken des Aha-Moments, aber erwarte nicht, dass es dich allgemein kl\xfcger macht.",faq:[["Macht mich das L\xf6sen von Anagrammen insgesamt kl\xfcger?","Realistisch betrachtet nein. Du wirst sp\xfcrbar besser bei Anagrammen und beim Abrufen von W\xf6rtern, aber es gibt keinen soliden Beleg daf\xfcr, dass sich die F\xe4higkeit auf die allgemeine Intelligenz oder andere geistige Aufgaben \xfcbertr\xe4gt."],["Hilft es tats\xe4chlich meinem Wortschatz?","Es trainiert den Wortschatz, den du bereits hast, indem es schnelles Abrufen erzwingt, und l\xe4ngere oder thematische S\xe4tze k\xf6nnen dich mit neuen W\xf6rtern in Kontakt bringen, aber es ist eher eine Sch\xe4rfungs\xfcbung als ein Weg, viele W\xf6rter von Grund auf zu lernen."],["Ich starre immer wieder auf dieselbe falsche Anordnung. Was hilft?","Zerlege die Buchstaben: Trenne Vokale von Konsonanten, suche nach vertrauten Endungen und schiebe die Kacheln tats\xe4chlich um, statt dich festzubei\xdfen. Die erste Vermutung loszulassen ist meist der Zug, der die Sache l\xf6st."]],variants:"\xdcbliche Varianten sind Buchstabengewirr mit fester L\xe4nge, Runden gegen die Uhr, thematische Buchstabens\xe4tze, das Bilden m\xf6glichst vieler kleinerer W\xf6rter aus einem langen Wort sowie ein ansteigender Schwierigkeitsgrad, bei dem die W\xf6rter mit dem Fortschritt l\xe4nger werden."},pt:{about:"Um anagrama te apresenta um conjunto de letras embaralhadas, e sua tarefa \xe9 reorganiz\xe1-las at\xe9 formar uma palavra real. Voc\xea l\xea a bagun\xe7a, procura um padr\xe3o e digita ou toca as letras na ordem certa antes que o tempo da rodada acabe.",benefit:"Ele exercita sua mem\xf3ria de trabalho verbal e seu l\xe9xico mental: voc\xea precisa segurar as letras na cabe\xe7a, manipul\xe1-las e vasculhar rapidamente o vocabul\xe1rio em busca de uma palavra que se encaixe. Tamb\xe9m treina o pensamento flex\xedvel, capaz de romper com o \xf3bvio, j\xe1 que o arranjo mais imediato costuma ser um beco sem sa\xedda.",history:"Reorganizar letras \xe9 algo que remonta aos antigos gregos, que usavam a t\xe9cnica para extrair sentidos ocultos de nomes, e aparece em escritos talm\xfadicos, midr\xe1shicos e cabal\xedsticos (a t\xe9cnica chamada temurah). Os anagramas foram populares por toda a Europa medieval e do in\xedcio da era moderna, eram valorizados como jogo de palavras engenhoso em latim e chegaram at\xe9 a ganhar regras formais, como as de George Puttenham em 1589.",creator:"N\xe3o h\xe1 um \xfanico inventor. O anagrama \xe9 uma tradi\xe7\xe3o popular de jogo de palavras com ra\xedzes gregas, muitas vezes associada ao poeta L\xedcofron no s\xe9culo III a.C., embora essa atribui\xe7\xe3o se apoie num relato bem posterior, do s\xe9culo XII, de Jo\xe3o Tzetzes. J\xe1 no s\xe9culo XVII ele era popular o bastante para que o rei Lu\xeds XIII mantivesse Thomas Billon como Anagramatista Real assalariado.",methods:"Procure primeiro termina\xe7\xf5es comuns (-ING, -ED, -TION, ou em portugu\xeas -\xc7\xc3O, -MENTE) e prefixos, e depois construa o resto em torno deles. Separe vogais e consoantes para enxergar a mat\xe9ria-prima, busque pares de letras prov\xe1veis (TH, CH, ST) e mexa fisicamente nas pe\xe7as em vez de s\xf3 encarar a tela, porque movimentar as letras costuma destravar a solu\xe7\xe3o. Se voc\xea empacar numa arruma\xe7\xe3o, abandone-a de prop\xf3sito: aquele primeiro palpite fixo \xe9 normalmente o que est\xe1 te bloqueando.",duration:"Sess\xf5es curtas e frequentes batem as maratonas: de 5 a 10 minutos, algumas vezes por semana, j\xe1 basta. Pare quando perceber que est\xe1 travando, pois o cansa\xe7o deixa a busca pela palavra mais lenta, n\xe3o mais afiada.",research:"As evid\xeancias s\xe3o mais fortes para o \xf3bvio: voc\xea fica mais r\xe1pido e mais preciso em resolver anagramas e em recuperar palavras. As promessas maiores s\xe3o bem mais fr\xe1geis: n\xe3o h\xe1 prova convincente de que praticar anagramas eleve a intelig\xeancia geral ou se transfira para habilidades n\xe3o relacionadas, e os conhecidos estudos que ligam jogos de palavras ao adiamento do decl\xednio de mem\xf3ria s\xe3o observacionais, ou seja, mostram associa\xe7\xe3o, n\xe3o que os jogos a tenham causado. Trate as grandes alega\xe7\xf5es com cautela e aproveite o que ele de fato oferece.",rec:"Resolva algumas palavras por dia pelo exerc\xedcio de vocabul\xe1rio e pelo prazer do estalo de descoberta, mas n\xe3o espere que isso te deixe mais inteligente de forma geral.",faq:[["Resolver anagramas vai me deixar mais inteligente de modo geral?","Sendo realista, n\xe3o. Voc\xea vai ficar visivelmente melhor em anagramas e em trazer palavras \xe0 mente, mas n\xe3o h\xe1 evid\xeancia s\xf3lida de que essa habilidade se espalhe para a intelig\xeancia geral ou para tarefas mentais n\xe3o relacionadas."],["Isso ajuda mesmo o meu vocabul\xe1rio?","Ele exercita o vocabul\xe1rio que voc\xea j\xe1 tem ao for\xe7ar uma recupera\xe7\xe3o r\xe1pida, e conjuntos mais longos ou tem\xe1ticos podem te expor a palavras novas, mas \xe9 mais um exerc\xedcio de afia\xe7\xe3o do que um jeito de aprender muitas palavras do zero."],["Eu travo encarando o mesmo arranjo errado. O que ajuda?","Quebre as letras: separe vogais de consoantes, procure termina\xe7\xf5es familiares e reembaralhe fisicamente as pe\xe7as em vez de ficar fixado. Largar o seu primeiro palpite costuma ser o movimento que destrava."]],variants:"Varia\xe7\xf5es comuns incluem embaralhados de tamanho fixo, rodadas cronometradas contra o rel\xf3gio, conjuntos de letras tem\xe1ticos, formar o maior n\xfamero poss\xedvel de palavras menores a partir de uma palavra longa e dificuldade progressiva, em que as palavras v\xe3o ficando mais longas conforme voc\xea avan\xe7a."},hi:{about:"\u090f\u0928\u093e\u0917\u094d\u0930\u093e\u092e \u092a\u0939\u0947\u0932\u0940 \u092e\u0947\u0902 \u0906\u092a\u0915\u094b \u0905\u0915\u094d\u0937\u0930\u094b\u0902 \u0915\u093e \u090f\u0915 \u0909\u0932\u091d\u093e-\u092a\u0941\u0932\u091d\u093e \u0938\u092e\u0942\u0939 \u0926\u093f\u092f\u093e \u091c\u093e\u0924\u093e \u0939\u0948, \u0914\u0930 \u0906\u092a\u0915\u093e \u0915\u093e\u092e \u0909\u0928\u094d\u0939\u0947\u0902 \u092b\u093f\u0930 \u0938\u0947 \u091c\u092e\u093e\u0915\u0930 \u0915\u094b\u0908 \u0905\u0938\u0932\u0940 \u0936\u092c\u094d\u0926 \u092c\u0928\u093e\u0928\u093e \u0939\u094b\u0924\u093e \u0939\u0948\u0964 \u0906\u092a \u0917\u0921\u094d\u0921\u092e\u0921\u094d\u0921 \u0905\u0915\u094d\u0937\u0930\u094b\u0902 \u0915\u094b \u092a\u0922\u093c\u0924\u0947 \u0939\u0948\u0902, \u0915\u094b\u0908 \u092a\u0948\u091f\u0930\u094d\u0928 \u0916\u094b\u091c\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u0930\u093e\u0909\u0902\u0921 \u0916\u0924\u094d\u092e \u0939\u094b\u0928\u0947 \u0938\u0947 \u092a\u0939\u0932\u0947 \u0905\u0915\u094d\u0937\u0930\u094b\u0902 \u0915\u094b \u0938\u0939\u0940 \u0915\u094d\u0930\u092e \u092e\u0947\u0902 \u091f\u093e\u0907\u092a \u092f\u093e \u091f\u0948\u092a \u0915\u0930 \u0926\u0947\u0924\u0947 \u0939\u0948\u0902\u0964",benefit:"\u092f\u0939 \u0906\u092a\u0915\u0940 \u092e\u094c\u0916\u093f\u0915 \u0935\u0930\u094d\u0915\u093f\u0902\u0917 \u092e\u0947\u092e\u094b\u0930\u0940 \u0914\u0930 \u092e\u093e\u0928\u0938\u093f\u0915 \u0936\u092c\u094d\u0926\u0915\u094b\u0936 \u0926\u094b\u0928\u094b\u0902 \u092a\u0930 \u0915\u093e\u092e \u0915\u0930\u0924\u0940 \u0939\u0948: \u0906\u092a\u0915\u094b \u0905\u0915\u094d\u0937\u0930\u094b\u0902 \u0915\u094b \u0926\u093f\u092e\u093e\u0917 \u092e\u0947\u0902 \u0925\u093e\u092e\u0947 \u0930\u0916\u0928\u093e \u0939\u094b\u0924\u093e \u0939\u0948, \u0909\u0928\u094d\u0939\u0947\u0902 \u0907\u0927\u0930-\u0909\u0927\u0930 \u092a\u0932\u091f\u0928\u093e \u0939\u094b\u0924\u093e \u0939\u0948, \u0914\u0930 \u0924\u0947\u091c\u093c\u0940 \u0938\u0947 \u0905\u092a\u0928\u0940 \u0936\u092c\u094d\u0926-\u0938\u0902\u092a\u0926\u093e \u0916\u0902\u0917\u093e\u0932\u0915\u0930 \u0915\u094b\u0908 \u092b\u093f\u091f \u092c\u0948\u0920\u0928\u0947 \u0935\u093e\u0932\u093e \u0936\u092c\u094d\u0926 \u0922\u0942\u0901\u0922\u093c\u0928\u093e \u0939\u094b\u0924\u093e \u0939\u0948\u0964 \u092f\u0939 \u0932\u091a\u0940\u0932\u0940, \u0922\u0930\u094d\u0930\u093e \u0924\u094b\u0921\u093c\u0928\u0947 \u0935\u093e\u0932\u0940 \u0938\u094b\u091a \u0915\u094b \u092d\u0940 \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u093f\u0924 \u0915\u0930\u0924\u0940 \u0939\u0948, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u0938\u092c\u0938\u0947 \u092a\u0939\u0932\u0947 \u0926\u093f\u092e\u093e\u0917 \u092e\u0947\u0902 \u0906\u0928\u0947 \u0935\u093e\u0932\u0940 \u091c\u092e\u093e\u0935\u091f \u0906\u092e\u0924\u094c\u0930 \u092a\u0930 \u090f\u0915 \u092c\u0902\u0926 \u0917\u0932\u0940 \u0939\u094b\u0924\u0940 \u0939\u0948\u0964",history:"\u0905\u0915\u094d\u0937\u0930\u094b\u0902 \u0915\u094b \u092b\u093f\u0930 \u0938\u0947 \u091c\u092e\u093e\u0928\u0947 \u0915\u093e \u091a\u0932\u0928 \u092a\u094d\u0930\u093e\u091a\u0940\u0928 \u092f\u0942\u0928\u093e\u0928\u093f\u092f\u094b\u0902 \u0924\u0915 \u091c\u093e\u0924\u093e \u0939\u0948, \u091c\u094b \u0907\u0938\u0915\u093e \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0928\u093e\u092e\u094b\u0902 \u092e\u0947\u0902 \u091b\u093f\u092a\u0947 \u0905\u0930\u094d\u0925 \u0928\u093f\u0915\u093e\u0932\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0915\u0930\u0924\u0947 \u0925\u0947, \u0914\u0930 \u092f\u0939 \u0924\u093e\u0932\u092e\u0941\u0926\u0940, \u092e\u093f\u0926\u094d\u0930\u093e\u0936\u0940 \u0924\u0925\u093e \u0915\u092c\u093e\u0932\u093e\u0935\u093e\u0926\u0940 \u0932\u0947\u0916\u0928 \u092e\u0947\u0902 \u092d\u0940 \u092e\u093f\u0932\u0924\u093e \u0939\u0948 (\u0907\u0938 \u0924\u0915\u0928\u0940\u0915 \u0915\u094b \u0924\u0947\u092e\u0941\u0930\u093e\u0939 \u0915\u0939\u0924\u0947 \u0939\u0948\u0902)\u0964 \u090f\u0928\u093e\u0917\u094d\u0930\u093e\u092e \u092e\u0927\u094d\u092f\u0915\u093e\u0932\u0940\u0928 \u0914\u0930 \u0906\u0930\u0902\u092d\u093f\u0915-\u0906\u0927\u0941\u0928\u093f\u0915 \u092f\u0942\u0930\u094b\u092a \u092d\u0930 \u092e\u0947\u0902 \u0932\u094b\u0915\u092a\u094d\u0930\u093f\u092f \u0925\u0947, \u0932\u0948\u091f\u093f\u0928 \u092e\u0947\u0902 \u0907\u0928\u094d\u0939\u0947\u0902 \u091a\u0924\u0941\u0930 \u0936\u092c\u094d\u0926-\u0915\u094d\u0930\u0940\u0921\u093c\u093e \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u0938\u0930\u093e\u0939\u093e \u091c\u093e\u0924\u093e \u0925\u093e, \u0914\u0930 \u0907\u0928\u0915\u0947 \u0914\u092a\u091a\u093e\u0930\u093f\u0915 \u0928\u093f\u092f\u092e \u0924\u0915 \u092c\u0928 \u0917\u090f, \u091c\u0948\u0938\u0947 1589 \u092e\u0947\u0902 \u091c\u0949\u0930\u094d\u091c \u092a\u0941\u091f\u0928\u0939\u092e \u0915\u0947 \u092c\u0928\u093e\u090f \u0928\u093f\u092f\u092e\u0964",creator:"\u0907\u0938\u0915\u093e \u0915\u094b\u0908 \u090f\u0915 \u0906\u0935\u093f\u0937\u094d\u0915\u093e\u0930\u0915 \u0928\u0939\u0940\u0902 \u0939\u0948\u0964 \u090f\u0928\u093e\u0917\u094d\u0930\u093e\u092e \u090f\u0915 \u0932\u094b\u0915 \u0936\u092c\u094d\u0926-\u0915\u094d\u0930\u0940\u0921\u093c\u093e \u092a\u0930\u0902\u092a\u0930\u093e \u0939\u0948 \u091c\u093f\u0938\u0915\u0940 \u091c\u0921\u093c\u0947\u0902 \u092f\u0942\u0928\u093e\u0928\u0940 \u0939\u0948\u0902, \u0914\u0930 \u0907\u0938\u0947 \u0905\u0915\u094d\u0938\u0930 \u0924\u0940\u0938\u0930\u0940 \u0936\u0924\u093e\u092c\u094d\u0926\u0940 \u0908\u0938\u093e \u092a\u0942\u0930\u094d\u0935 \u0915\u0947 \u0915\u0935\u093f \u0932\u093e\u0907\u0915\u094b\u092b\u094d\u0930\u0949\u0928 \u0938\u0947 \u091c\u094b\u0921\u093c\u093e \u091c\u093e\u0924\u093e \u0939\u0948, \u0939\u093e\u0932\u093e\u0901\u0915\u093f \u092f\u0939 \u0936\u094d\u0930\u0947\u092f \u092c\u0939\u0941\u0924 \u092c\u093e\u0926 \u0915\u0947, \u092c\u093e\u0930\u0939\u0935\u0940\u0902 \u0938\u0926\u0940 \u0915\u0947 \u091c\u0949\u0928 \u0924\u094d\u091c\u0947\u0924\u094d\u091c\u0947\u0938 \u0915\u0947 \u0935\u093f\u0935\u0930\u0923 \u092a\u0930 \u091f\u093f\u0915\u093e \u0939\u0948\u0964 \u0938\u0924\u094d\u0930\u0939\u0935\u0940\u0902 \u0938\u0926\u0940 \u0924\u0915 \u092f\u0939 \u0907\u0924\u0928\u093e \u0932\u094b\u0915\u092a\u094d\u0930\u093f\u092f \u0939\u094b \u091a\u0941\u0915\u093e \u0925\u093e \u0915\u093f \u0930\u093e\u091c\u093e \u0932\u0941\u0908 \u0924\u0947\u0930\u0939\u0935\u0947\u0902 \u0928\u0947 \u0925\u0949\u092e\u0938 \u092c\u093f\u0932\u0949\u0928 \u0915\u094b \u0935\u0947\u0924\u0928\u092d\u094b\u0917\u0940 \u0930\u093e\u091c\u0915\u0940\u092f \u090f\u0928\u093e\u0917\u094d\u0930\u093e\u092e\u0935\u093f\u0926\u094d \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u0930\u0916\u093e \u0925\u093e\u0964",methods:"\u092a\u0939\u0932\u0947 \u0906\u092e \u0905\u0902\u0924 (-ING, -ED, -TION) \u0914\u0930 \u0909\u092a\u0938\u0930\u094d\u0917 \u0916\u094b\u091c\u0947\u0902, \u092b\u093f\u0930 \u092c\u093e\u0915\u0940 \u0936\u092c\u094d\u0926 \u0909\u0928\u094d\u0939\u0940\u0902 \u0915\u0947 \u0907\u0930\u094d\u0926-\u0917\u093f\u0930\u094d\u0926 \u0917\u0922\u093c\u0947\u0902\u0964 \u0938\u094d\u0935\u0930 \u0914\u0930 \u0935\u094d\u092f\u0902\u091c\u0928 \u0905\u0932\u0917-\u0905\u0932\u0917 \u0928\u093f\u0915\u093e\u0932\u0915\u0930 \u0915\u091a\u094d\u091a\u093e \u092e\u093e\u0932 \u0926\u0947\u0916 \u0932\u0947\u0902, \u0938\u0902\u092d\u093e\u0935\u093f\u0924 \u0905\u0915\u094d\u0937\u0930-\u091c\u094b\u0921\u093c\u094b\u0902 (TH, CH, ST) \u092a\u0930 \u0928\u091c\u093c\u0930 \u0930\u0916\u0947\u0902, \u0914\u0930 \u0938\u093f\u0930\u094d\u092b\u093c \u0918\u0942\u0930\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u0905\u0915\u094d\u0937\u0930\u094b\u0902 \u0915\u0947 \u091f\u0941\u0915\u0921\u093c\u094b\u0902 \u0915\u094b \u0938\u091a\u092e\u0941\u091a \u0907\u0927\u0930-\u0909\u0927\u0930 \u0939\u093f\u0932\u093e\u090f\u0901, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u0905\u0915\u094d\u0937\u0930\u094b\u0902 \u0915\u094b \u0938\u0930\u0915\u093e\u0928\u0947 \u092d\u0930 \u0938\u0947 \u0905\u0915\u094d\u0938\u0930 \u0939\u0932 \u0938\u0942\u091d \u091c\u093e\u0924\u093e \u0939\u0948\u0964 \u0905\u0917\u0930 \u0915\u093f\u0938\u0940 \u090f\u0915 \u091c\u092e\u093e\u0935\u091f \u092a\u0930 \u0905\u091f\u0915 \u091c\u093e\u090f\u0901, \u0924\u094b \u091c\u093e\u0928\u092c\u0942\u091d\u0915\u0930 \u0909\u0938\u0947 \u091b\u094b\u0921\u093c \u0926\u0947\u0902 \u2014 \u0935\u0939\u0940 \u092a\u0939\u0932\u093e \u0924\u092f \u0905\u0928\u0941\u092e\u093e\u0928 \u0906\u092e\u0924\u094c\u0930 \u092a\u0930 \u0930\u093e\u0938\u094d\u0924\u093e \u0930\u094b\u0915\u0947 \u0930\u0939\u0924\u093e \u0939\u0948\u0964",duration:"\u091b\u094b\u091f\u0947 \u0914\u0930 \u092c\u093e\u0930-\u092c\u093e\u0930 \u0915\u093f\u090f \u091c\u093e\u0928\u0947 \u0935\u093e\u0932\u0947 \u0938\u0924\u094d\u0930 \u0932\u0902\u092c\u0940 \u092e\u0948\u0930\u093e\u0925\u0928 \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u0939\u0948\u0902: \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u0915\u0941\u091b \u092c\u093e\u0930 5 \u0938\u0947 10 \u092e\u093f\u0928\u091f \u0915\u093e\u092b\u093c\u0940 \u0939\u0948\u0902\u0964 \u091c\u092c \u0906\u092a\u0915\u094b \u0932\u0917\u0947 \u0915\u093f \u0906\u092a \u0905\u091f\u0915\u0928\u0947 \u0932\u0917\u0947 \u0939\u0948\u0902 \u0924\u094b \u0930\u0941\u0915 \u091c\u093e\u090f\u0901 \u2014 \u0925\u0915\u093e\u0928 \u0938\u0947 \u0936\u092c\u094d\u0926-\u0916\u094b\u091c \u0927\u0940\u092e\u0940 \u0939\u094b\u0924\u0940 \u0939\u0948, \u0924\u0947\u091c\u093c \u0928\u0939\u0940\u0902\u0964",research:"\u092a\u094d\u0930\u092e\u093e\u0923 \u0938\u092c\u0938\u0947 \u0920\u094b\u0938 \u0909\u0938\u0940 \u091c\u093c\u093e\u0939\u093f\u0930 \u092c\u093e\u0924 \u0915\u0947 \u0932\u093f\u090f \u0939\u0948\u0902 \u2014 \u0906\u092a \u090f\u0928\u093e\u0917\u094d\u0930\u093e\u092e \u0939\u0932 \u0915\u0930\u0928\u0947 \u0914\u0930 \u0936\u092c\u094d\u0926 \u092f\u093e\u0926 \u0915\u0930\u0928\u0947 \u092e\u0947\u0902 \u0924\u0947\u091c\u093c \u0914\u0930 \u0938\u091f\u0940\u0915 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902\u0964 \u0907\u0938\u0938\u0947 \u092c\u0921\u093c\u0947 \u0935\u093e\u0926\u0947 \u0915\u0939\u0940\u0902 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0921\u0917\u092e\u0917\u093e\u0924\u0947 \u0939\u0948\u0902: \u0907\u0938\u0915\u093e \u0915\u094b\u0908 \u092a\u0941\u0916\u094d\u0924\u093e \u092a\u094d\u0930\u092e\u093e\u0923 \u0928\u0939\u0940\u0902 \u0915\u093f \u090f\u0928\u093e\u0917\u094d\u0930\u093e\u092e \u0905\u092d\u094d\u092f\u093e\u0938 \u0938\u0947 \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u092c\u0941\u0926\u094d\u0927\u093f \u092c\u0922\u093c\u0924\u0940 \u0939\u0948 \u092f\u093e \u0905\u0938\u0902\u092c\u0902\u0927\u093f\u0924 \u0915\u094c\u0936\u0932\u094b\u0902 \u092e\u0947\u0902 \u092b\u093c\u093e\u092f\u0926\u093e \u092a\u0939\u0941\u0901\u091a\u0924\u093e \u0939\u0948, \u0914\u0930 \u0936\u092c\u094d\u0926-\u092a\u0939\u0947\u0932\u093f\u092f\u094b\u0902 \u0915\u094b \u092f\u093e\u0926\u0926\u093e\u0936\u094d\u0924 \u0915\u0940 \u0926\u0947\u0930\u0940 \u0938\u0947 \u0939\u094b\u0928\u0947 \u0935\u093e\u0932\u0940 \u0917\u093f\u0930\u093e\u0935\u091f \u0938\u0947 \u091c\u094b\u0921\u093c\u0928\u0947 \u0935\u093e\u0932\u0947 \u092e\u0936\u0939\u0942\u0930 \u0905\u0927\u094d\u092f\u092f\u0928 \u092a\u094d\u0930\u0947\u0915\u094d\u0937\u0923\u093e\u0924\u094d\u092e\u0915 \u0939\u0948\u0902, \u092f\u093e\u0928\u0940 \u0935\u0947 \u0915\u0947\u0935\u0932 \u0938\u0902\u092c\u0902\u0927 \u0926\u093f\u0916\u093e\u0924\u0947 \u0939\u0948\u0902, \u092f\u0939 \u0928\u0939\u0940\u0902 \u0915\u093f \u092a\u0939\u0947\u0932\u093f\u092f\u094b\u0902 \u0928\u0947 \u0910\u0938\u093e \u0915\u093f\u092f\u093e\u0964 \u092c\u0921\u093c\u0947-\u092c\u0921\u093c\u0947 \u0926\u093e\u0935\u094b\u0902 \u0915\u094b \u0938\u093e\u0935\u0927\u093e\u0928\u0940 \u0938\u0947 \u0932\u0947\u0902 \u0914\u0930 \u0907\u0938\u0915\u093e \u0906\u0928\u0902\u0926 \u0909\u0938\u0940 \u0915\u0947 \u0932\u093f\u090f \u0932\u0947\u0902 \u091c\u094b \u092f\u0939 \u092d\u0930\u094b\u0938\u0947 \u0938\u0947 \u0926\u0947\u0924\u0940 \u0939\u0948\u0964",rec:"\u0936\u092c\u094d\u0926-\u0938\u0902\u092a\u0926\u093e \u0915\u0940 \u0915\u0938\u0930\u0924 \u0914\u0930 \u0905\u0902\u0924\u0930\u094d\u0926\u0943\u0937\u094d\u091f\u093f \u0915\u0947 \u0938\u0902\u0924\u094b\u0937\u091c\u0928\u0915 '\u0915\u094d\u0932\u093f\u0915' \u0915\u0947 \u0932\u093f\u090f \u0930\u094b\u091c\u093c \u0915\u0941\u091b \u0936\u092c\u094d\u0926 \u0939\u0932 \u0915\u0930\u0947\u0902, \u092a\u0930 \u092f\u0939 \u0909\u092e\u094d\u092e\u0940\u0926 \u0928 \u0930\u0916\u0947\u0902 \u0915\u093f \u0907\u0938\u0938\u0947 \u0906\u092a \u0915\u0941\u0932 \u092e\u093f\u0932\u093e\u0915\u0930 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u092c\u0941\u0926\u094d\u0927\u093f\u092e\u093e\u0928 \u092c\u0928 \u091c\u093e\u090f\u0901\u0917\u0947\u0964",faq:[["\u0915\u094d\u092f\u093e \u090f\u0928\u093e\u0917\u094d\u0930\u093e\u092e \u0939\u0932 \u0915\u0930\u0928\u0947 \u0938\u0947 \u092e\u0948\u0902 \u0915\u0941\u0932 \u092e\u093f\u0932\u093e\u0915\u0930 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u092c\u0941\u0926\u094d\u0927\u093f\u092e\u093e\u0928 \u092c\u0928 \u091c\u093e\u090a\u0901\u0917\u093e?","\u0938\u091a \u0915\u0939\u0947\u0902 \u0924\u094b \u0928\u0939\u0940\u0902\u0964 \u0906\u092a \u090f\u0928\u093e\u0917\u094d\u0930\u093e\u092e \u092e\u0947\u0902 \u0914\u0930 \u0936\u092c\u094d\u0926\u094b\u0902 \u0915\u094b \u092f\u093e\u0926 \u0915\u0930\u0928\u0947 \u092e\u0947\u0902 \u0938\u093e\u092b\u093c \u0924\u094c\u0930 \u092a\u0930 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u090f\u0901\u0917\u0947, \u092a\u0930 \u0907\u0938\u0915\u093e \u0915\u094b\u0908 \u0920\u094b\u0938 \u092a\u094d\u0930\u092e\u093e\u0923 \u0928\u0939\u0940\u0902 \u0915\u093f \u092f\u0939 \u0915\u094c\u0936\u0932 \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u092c\u0941\u0926\u094d\u0927\u093f \u092f\u093e \u0905\u0938\u0902\u092c\u0902\u0927\u093f\u0924 \u092e\u093e\u0928\u0938\u093f\u0915 \u0915\u093e\u092e\u094b\u0902 \u0924\u0915 \u092b\u0948\u0932\u0924\u093e \u0939\u0948\u0964"],["\u0915\u094d\u092f\u093e \u092f\u0939 \u0938\u091a\u092e\u0941\u091a \u092e\u0947\u0930\u0940 \u0936\u092c\u094d\u0926-\u0938\u0902\u092a\u0926\u093e \u092e\u0947\u0902 \u092e\u0926\u0926 \u0915\u0930\u0924\u093e \u0939\u0948?","\u092f\u0939 \u0906\u092a\u0915\u0940 \u092a\u0939\u0932\u0947 \u0938\u0947 \u092e\u094c\u091c\u0942\u0926 \u0936\u092c\u094d\u0926-\u0938\u0902\u092a\u0926\u093e \u0915\u0940 \u0915\u0938\u0930\u0924 \u0915\u0930\u093e\u0924\u093e \u0939\u0948, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u092f\u0939 \u0924\u0947\u091c\u093c\u0940 \u0938\u0947 \u0936\u092c\u094d\u0926 \u092f\u093e\u0926 \u0915\u0930\u0928\u0947 \u092a\u0930 \u092e\u091c\u092c\u0942\u0930 \u0915\u0930\u0924\u093e \u0939\u0948, \u0914\u0930 \u0932\u0902\u092c\u0947 \u092f\u093e \u0935\u093f\u0937\u092f-\u0906\u0927\u093e\u0930\u093f\u0924 \u0938\u092e\u0942\u0939 \u0906\u092a\u0915\u094b \u0928\u090f \u0936\u092c\u094d\u0926\u094b\u0902 \u0938\u0947 \u0930\u0942\u092c\u0930\u0942 \u0915\u0930\u093e \u0938\u0915\u0924\u0947 \u0939\u0948\u0902, \u092a\u0930 \u092f\u0939 \u0928\u090f \u0938\u093f\u0930\u0947 \u0938\u0947 \u0922\u0947\u0930\u094b\u0902 \u0936\u092c\u094d\u0926 \u0938\u0940\u0916\u0928\u0947 \u0915\u093e \u091c\u093c\u0930\u093f\u092f\u093e \u0915\u092e \u0914\u0930 \u0927\u093e\u0930 \u0924\u0947\u091c\u093c \u0915\u0930\u0928\u0947 \u0935\u093e\u0932\u0940 \u0915\u0938\u0930\u0924 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0939\u0948\u0964"],["\u092e\u0948\u0902 \u0909\u0938\u0940 \u0917\u0932\u0924 \u091c\u092e\u093e\u0935\u091f \u0915\u094b \u0918\u0942\u0930\u0924\u093e \u0930\u0939 \u091c\u093e\u0924\u093e \u0939\u0942\u0901\u0964 \u0915\u094d\u092f\u093e \u092e\u0926\u0926 \u0915\u0930\u0924\u093e \u0939\u0948?","\u0905\u0915\u094d\u0937\u0930\u094b\u0902 \u0915\u094b \u0924\u094b\u0921\u093c \u0921\u093e\u0932\u0947\u0902: \u0938\u094d\u0935\u0930\u094b\u0902 \u0915\u094b \u0935\u094d\u092f\u0902\u091c\u0928\u094b\u0902 \u0938\u0947 \u0905\u0932\u0917 \u0915\u0930\u0947\u0902, \u091c\u093e\u0928\u0947-\u092a\u0939\u091a\u093e\u0928\u0947 \u0905\u0902\u0924 \u0916\u094b\u091c\u0947\u0902, \u0914\u0930 \u091f\u0915\u091f\u0915\u0940 \u0932\u0917\u093e\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u0905\u0915\u094d\u0937\u0930\u094b\u0902 \u0915\u0947 \u091f\u0941\u0915\u0921\u093c\u094b\u0902 \u0915\u094b \u0938\u091a\u092e\u0941\u091a \u092b\u093f\u0930 \u0938\u0947 \u0938\u0930\u0915\u093e\u090f\u0901\u0964 \u0905\u092a\u0928\u0947 \u092a\u0939\u0932\u0947 \u0905\u0928\u0941\u092e\u093e\u0928 \u0915\u094b \u091b\u094b\u0921\u093c \u0926\u0947\u0928\u093e \u0939\u0940 \u0906\u092e\u0924\u094c\u0930 \u092a\u0930 \u0935\u0939 \u0915\u0926\u092e \u0939\u0948 \u091c\u094b \u0924\u093e\u0932\u093e \u0916\u094b\u0932 \u0926\u0947\u0924\u093e \u0939\u0948\u0964"]],variants:"\u0906\u092e \u0930\u0942\u092a\u094b\u0902 \u092e\u0947\u0902 \u0924\u092f-\u0932\u0902\u092c\u093e\u0908 \u0935\u093e\u0932\u0947 \u0909\u0932\u091d\u0947 \u0905\u0915\u094d\u0937\u0930, \u0918\u0921\u093c\u0940 \u0915\u0947 \u0935\u093f\u0930\u0941\u0926\u094d\u0927 \u0938\u092e\u092f\u092c\u0926\u094d\u0927 \u0930\u093e\u0909\u0902\u0921, \u0935\u093f\u0937\u092f-\u0906\u0927\u093e\u0930\u093f\u0924 \u0905\u0915\u094d\u0937\u0930-\u0938\u092e\u0942\u0939, \u090f\u0915 \u0932\u0902\u092c\u0947 \u0936\u092c\u094d\u0926 \u0938\u0947 \u0905\u0927\u093f\u0915 \u0938\u0947 \u0905\u0927\u093f\u0915 \u091b\u094b\u091f\u0947 \u0936\u092c\u094d\u0926 \u092c\u0928\u093e\u0928\u093e, \u0914\u0930 \u0915\u094d\u0930\u092e\u093f\u0915 \u0915\u0920\u093f\u0928\u093e\u0908 \u0936\u093e\u092e\u093f\u0932 \u0939\u0948 \u091c\u0939\u093e\u0901 \u0906\u0917\u0947 \u092c\u0922\u093c\u0928\u0947 \u092a\u0930 \u0936\u092c\u094d\u0926 \u0932\u0902\u092c\u0947 \u0939\u094b\u0924\u0947 \u091c\u093e\u0924\u0947 \u0939\u0948\u0902\u0964"},zh:{about:"\u5b57\u6bcd\u91cd\u7ec4\u8c1c\u9898\u4f1a\u7ed9\u4f60\u4e00\u7ec4\u6253\u4e71\u987a\u5e8f\u7684\u5b57\u6bcd\uff0c\u4f60\u7684\u4efb\u52a1\u662f\u628a\u5b83\u4eec\u91cd\u65b0\u6392\u5217\u6210\u4e00\u4e2a\u771f\u6b63\u7684\u5355\u8bcd\u3002\u4f60\u8981\u770b\u7740\u8fd9\u5806\u4e71\u5e8f\u7684\u5b57\u6bcd\uff0c\u5bfb\u627e\u5176\u4e2d\u7684\u89c4\u5f8b\uff0c\u5728\u672c\u8f6e\u7ed3\u675f\u524d\u628a\u5b57\u6bcd\u6309\u6b63\u786e\u7684\u987a\u5e8f\u6572\u51fa\u6765\u6216\u70b9\u51fa\u6765\u3002",benefit:"\u5b83\u953b\u70bc\u7684\u662f\u4f60\u7684\u8a00\u8bed\u5de5\u4f5c\u8bb0\u5fc6\u548c\u5fc3\u7406\u8bcd\u5e93\uff1a\u4f60\u5fc5\u987b\u5728\u8111\u4e2d\u8bb0\u4f4f\u8fd9\u4e9b\u5b57\u6bcd\uff0c\u53cd\u590d\u8c03\u6362\u5b83\u4eec\u7684\u4f4d\u7f6e\uff0c\u5e76\u5feb\u901f\u641c\u7d22\u8bcd\u6c47\u5e93\uff0c\u627e\u5230\u4e00\u4e2a\u80fd\u5bf9\u4e0a\u7684\u5355\u8bcd\u3002\u5b83\u540c\u65f6\u8fd8\u8bad\u7ec3\u7075\u6d3b\u7684\u3001\u80fd\u8df3\u51fa\u5b9a\u5f0f\u7684\u601d\u7ef4\uff0c\u56e0\u4e3a\u90a3\u4e2a\u6700\u663e\u800c\u6613\u89c1\u7684\u6392\u5217\u65b9\u5f0f\u5f80\u5f80\u662f\u6761\u6b7b\u8def\u3002",history:"\u5b57\u6bcd\u91cd\u6392\u7684\u5386\u53f2\u53ef\u4ee5\u8ffd\u6eaf\u5230\u53e4\u5e0c\u814a\u4eba\uff0c\u4ed6\u4eec\u7528\u5b83\u4ece\u540d\u5b57\u91cc\u6316\u51fa\u9690\u85cf\u7684\u542b\u4e49\uff0c\u8fd9\u79cd\u624b\u6cd5\u4e5f\u51fa\u73b0\u5728\u5854\u6728\u5fb7\u3001\u7c73\u5fb7\u62c9\u4ec0\u548c\u5361\u5df4\u62c9\u7684\u8457\u4f5c\u4e2d\uff08\u5373\u6240\u8c13\u7684 temurah \u6280\u6cd5\uff09\u3002\u5b57\u6bcd\u91cd\u7ec4\u8c1c\u5728\u4e2d\u4e16\u7eaa\u548c\u8fd1\u4ee3\u65e9\u671f\u7684\u6b27\u6d32\u5341\u5206\u6d41\u884c\uff0c\u5728\u62c9\u4e01\u6587\u91cc\u88ab\u89c6\u4e3a\u5de7\u5999\u7684\u6587\u5b57\u6e38\u620f\u800c\u5907\u53d7\u63a8\u5d07\uff0c\u751a\u81f3\u8fd8\u5f62\u6210\u4e86\u6b63\u5f0f\u7684\u89c4\u5219\uff0c\u6bd4\u5982\u4e54\u6cbb\xb7\u666e\u7279\u7eb3\u59c6\uff08George Puttenham\uff09\u57281589\u5e74\u5236\u5b9a\u7684\u90a3\u4e00\u5957\u3002",creator:"\u5b83\u6ca1\u6709\u5355\u4e00\u7684\u53d1\u660e\u8005\u3002\u5b57\u6bcd\u91cd\u7ec4\u662f\u4e00\u9879\u6709\u7740\u5e0c\u814a\u6e0a\u6e90\u7684\u6c11\u95f4\u6587\u5b57\u6e38\u620f\u4f20\u7edf\uff0c\u5e38\u5e38\u88ab\u5f52\u5230\u516c\u5143\u524d3\u4e16\u7eaa\u7684\u8bd7\u4eba\u5415\u79d1\u4f5b\u9686\uff08Lycophron\uff09\u540d\u4e0b\uff0c\u4e0d\u8fc7\u8fd9\u79cd\u8bf4\u6cd5\u6240\u4f9d\u636e\u7684\uff0c\u662f\u7ea6\u7ff0\xb7\u7b56\u7b56\u65af\uff08John Tzetzes\uff09\u572812\u4e16\u7eaa\u5199\u4e0b\u7684\u3001\u5e74\u4ee3\u8981\u665a\u5f97\u591a\u7684\u8bb0\u8f7d\u3002\u5230\u4e8617\u4e16\u7eaa\uff0c\u5b83\u5df2\u7ecf\u6d41\u884c\u5230\u8fd9\u822c\u5730\u6b65\u2014\u2014\u6cd5\u738b\u8def\u6613\u5341\u4e09\u8fd8\u4e13\u95e8\u96c7\u4e86\u6258\u9a6c\u65af\xb7\u6bd4\u6c38\uff08Thomas Billon\uff09\u62c5\u4efb\u9886\u85aa\u7684\u300c\u7687\u5bb6\u5b57\u8c1c\u5e08\u300d\u3002",methods:"\u5148\u626b\u4e00\u904d\u5e38\u89c1\u7684\u8bcd\u5c3e\uff08-ING\u3001-ED\u3001-TION\uff09\u548c\u8bcd\u5934\uff0c\u7136\u540e\u56f4\u7ed5\u5b83\u4eec\u628a\u5269\u4e0b\u7684\u90e8\u5206\u642d\u8d77\u6765\u3002\u628a\u5143\u97f3\u548c\u8f85\u97f3\u5206\u522b\u62ce\u51fa\u6765\uff0c\u770b\u6e05\u4f60\u624b\u4e0a\u7684\u300c\u539f\u6599\u300d\uff0c\u7559\u610f\u53ef\u80fd\u6210\u5bf9\u51fa\u73b0\u7684\u5b57\u6bcd\uff08TH\u3001CH\u3001ST\uff09\uff0c\u5e76\u4e14\u8981\u771f\u7684\u53bb\u52a8\u624b\u632a\u52a8\u5b57\u6bcd\u724c\uff0c\u800c\u4e0d\u662f\u5e72\u77aa\u7740\u2014\u2014\u79fb\u52a8\u5b57\u6bcd\u8fd9\u4e2a\u52a8\u4f5c\u672c\u8eab\u5f80\u5f80\u5c31\u80fd\u89e6\u53d1\u7b54\u6848\u3002\u5982\u679c\u4f60\u5361\u5728\u67d0\u4e00\u79cd\u6392\u5217\u4e0a\u51fa\u4e0d\u6765\uff0c\u5c31\u523b\u610f\u628a\u5b83\u4e22\u6389\uff0c\u90a3\u4e2a\u56fa\u6267\u7684\u7b2c\u4e00\u611f\u5f80\u5f80\u6b63\u662f\u5835\u4f4f\u4f60\u601d\u8def\u7684\u4e1c\u897f\u3002",duration:"\u77ed\u800c\u9891\u7e41\u7684\u7ec3\u4e60\u80dc\u8fc7\u9a6c\u62c9\u677e\u5f0f\u7684\u6b7b\u78d5\uff1a\u6bcf\u5468\u7ec3\u51e0\u6b21\u3001\u6bcf\u6b215\u523010\u5206\u949f\u5c31\u8db3\u591f\u4e86\u3002\u5f53\u4f60\u53d1\u73b0\u81ea\u5df1\u5f00\u59cb\u5361\u58f3\u65f6\u5c31\u505c\u4e0b\u6765\u2014\u2014\u75b2\u52b3\u53ea\u4f1a\u8ba9\u627e\u8bcd\u53d8\u6162\uff0c\u800c\u4e0d\u4f1a\u8ba9\u4f60\u53d8\u5f97\u66f4\u654f\u9510\u3002",research:"\u8bc1\u636e\u6700\u624e\u5b9e\u7684\uff0c\u6070\u6070\u662f\u90a3\u4e2a\u6700\u663e\u800c\u6613\u89c1\u7684\u7ed3\u8bba\uff1a\u4f60\u4f1a\u53d8\u5f97\u66f4\u5feb\u3001\u66f4\u51c6\u5730\u89e3\u51fa\u5b57\u6bcd\u91cd\u7ec4\u8c1c\uff0c\u4e5f\u66f4\u5584\u4e8e\u628a\u5355\u8bcd\u4ece\u8bb0\u5fc6\u91cc\u8c03\u53d6\u51fa\u6765\u3002\u90a3\u4e9b\u66f4\u5b8f\u5927\u7684\u627f\u8bfa\u5219\u8981\u9760\u4e0d\u4f4f\u5f97\u591a\uff1a\u6ca1\u6709\u4efb\u4f55\u4ee4\u4eba\u4fe1\u670d\u7684\u8bc1\u636e\u8868\u660e\uff0c\u7ec3\u5b57\u8c1c\u80fd\u63d0\u5347\u4e00\u822c\u667a\u529b\u6216\u8fc1\u79fb\u5230\u65e0\u5173\u7684\u6280\u80fd\u4e0a\uff1b\u800c\u90a3\u4e9b\u5e7f\u4e3a\u4eba\u77e5\u7684\u3001\u628a\u6587\u5b57\u8c1c\u9898\u4e0e\u5ef6\u7f13\u8bb0\u5fc6\u8870\u9000\u8054\u7cfb\u8d77\u6765\u7684\u7814\u7a76\u90fd\u5c5e\u4e8e\u89c2\u5bdf\u6027\u7814\u7a76\uff0c\u6240\u4ee5\u5b83\u4eec\u53ea\u80fd\u8bf4\u660e\u4e24\u8005\u5b58\u5728\u5173\u8054\uff0c\u5e76\u4e0d\u80fd\u8bc1\u660e\u662f\u8c1c\u9898\u5e26\u6765\u4e86\u8fd9\u79cd\u6548\u679c\u3002\u5bf9\u90a3\u4e9b\u5b8f\u5927\u7684\u8bf4\u6cd5\u8981\u4fdd\u6301\u8c28\u614e\uff0c\u628a\u5b83\u5f53\u4f5c\u5b83\u786e\u5b9e\u80fd\u505a\u5230\u7684\u4e8b\u60c5\u6765\u4eab\u53d7\u5c31\u597d\u3002",rec:"\u6bcf\u5929\u89e3\u4e0a\u51e0\u4e2a\u5355\u8bcd\uff0c\u4eab\u53d7\u8fd9\u4efd\u8bcd\u6c47\u8bad\u7ec3\u4ee5\u53ca\u7075\u5149\u4e4d\u73b0\u65f6\u90a3\u300c\u5494\u54d2\u300d\u4e00\u58f0\u7684\u6ee1\u8db3\u611f\uff0c\u4f46\u522b\u6307\u671b\u5b83\u80fd\u8ba9\u4f60\u6574\u4f53\u4e0a\u53d8\u5f97\u66f4\u806a\u660e\u3002",faq:[["\u89e3\u5b57\u6bcd\u91cd\u7ec4\u8c1c\u4f1a\u8ba9\u6211\u6574\u4f53\u4e0a\u53d8\u806a\u660e\u5417\uff1f","\u73b0\u5b9e\u70b9\u8bf4\uff0c\u4e0d\u4f1a\u3002\u4f60\u4f1a\u5728\u89e3\u5b57\u8c1c\u548c\u628a\u5355\u8bcd\u8c03\u53d6\u5230\u8111\u4e2d\u8fd9\u4e24\u4ef6\u4e8b\u4e0a\u660e\u663e\u53d8\u5f3a\uff0c\u4f46\u6ca1\u6709\u786e\u51ff\u7684\u8bc1\u636e\u8868\u660e\u8fd9\u9879\u6280\u80fd\u4f1a\u6269\u6563\u5230\u4e00\u822c\u667a\u529b\u6216\u65e0\u5173\u7684\u8111\u529b\u4efb\u52a1\u4e0a\u3002"],["\u5b83\u5bf9\u6211\u7684\u8bcd\u6c47\u91cf\u771f\u6709\u5e2e\u52a9\u5417\uff1f","\u5b83\u901a\u8fc7\u5f3a\u8feb\u4f60\u5feb\u901f\u8c03\u53d6\uff0c\u6765\u953b\u70bc\u4f60\u5df2\u7ecf\u638c\u63e1\u7684\u8bcd\u6c47\uff1b\u66f4\u957f\u6216\u5e26\u4e3b\u9898\u7684\u5b57\u6bcd\u7ec4\u4e5f\u53ef\u80fd\u8ba9\u4f60\u63a5\u89e6\u5230\u65b0\u8bcd\u3002\u4f46\u5b83\u66f4\u50cf\u662f\u4e00\u79cd\u6253\u78e8\u6280\u80fd\u7684\u8bad\u7ec3\uff0c\u800c\u4e0d\u662f\u4ece\u96f6\u5f00\u59cb\u5927\u91cf\u5b66\u65b0\u8bcd\u7684\u9014\u5f84\u3002"],["\u6211\u8001\u662f\u76ef\u7740\u540c\u4e00\u4e2a\u9519\u8bef\u6392\u5217\u51fa\u4e0d\u6765\uff0c\u600e\u4e48\u529e\uff1f","\u628a\u5b57\u6bcd\u6253\u6563\uff1a\u628a\u5143\u97f3\u548c\u8f85\u97f3\u5206\u5f00\uff0c\u627e\u719f\u6089\u7684\u8bcd\u5c3e\uff0c\u5e76\u4e14\u52a8\u624b\u91cd\u65b0\u6d17\u4e00\u904d\u5b57\u6bcd\u724c\uff0c\u800c\u4e0d\u662f\u6b7b\u76ef\u7740\u4e0d\u653e\u3002\u653e\u4e0b\u4f60\u7684\u7b2c\u4e00\u611f\uff0c\u901a\u5e38\u6b63\u662f\u89e3\u5f00\u5b83\u7684\u90a3\u4e00\u6b65\u3002"]],variants:"\u5e38\u89c1\u7684\u53d8\u4f53\u5305\u62ec\uff1a\u56fa\u5b9a\u5b57\u6bcd\u6570\u7684\u4e71\u5e8f\u9898\u3001\u4e0e\u65f6\u95f4\u8d5b\u8dd1\u7684\u9650\u65f6\u56de\u5408\u3001\u56f4\u7ed5\u4e3b\u9898\u9009\u53d6\u7684\u5b57\u6bcd\u7ec4\u3001\u4ece\u4e00\u4e2a\u957f\u5355\u8bcd\u4e2d\u5c3d\u53ef\u80fd\u591a\u5730\u62fc\u51fa\u5c0f\u5355\u8bcd\uff0c\u4ee5\u53ca\u96be\u5ea6\u9012\u8fdb\u5f0f\u2014\u2014\u968f\u7740\u4f60\u7684\u63a8\u8fdb\uff0c\u5355\u8bcd\u4f1a\u8d8a\u6765\u8d8a\u957f\u3002"}},ant:{ru:{about:"ANT \u2014 \u044d\u0442\u043e \u0437\u0430\u0434\u0430\u0447\u0430 \u0441 \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u043a\u043e\u0439 \u0438 \u0441\u0442\u0440\u0435\u043b\u043a\u0430\u043c\u0438. \u0412 \u043a\u0430\u0436\u0434\u043e\u0439 \u043f\u0440\u043e\u0431\u0435 \u0432\u044b \u0436\u0434\u0451\u0442\u0435 \u043a\u0440\u0435\u0441\u0442\u0438\u043a \u0432 \u0446\u0435\u043d\u0442\u0440\u0435, \u0438\u043d\u043e\u0433\u0434\u0430 \u0432\u0438\u0434\u0438\u0442\u0435 \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u043a\u0443 (\u0432\u0441\u043f\u044b\u0448\u043a\u0443 \u0441\u0432\u0435\u0440\u0445\u0443 \u0438\u043b\u0438 \u0441\u043d\u0438\u0437\u0443 \u2014 \u0442\u0430\u043c, \u0433\u0434\u0435 \u043f\u043e\u044f\u0432\u0438\u0442\u0441\u044f \u0446\u0435\u043b\u044c), \u0437\u0430\u0442\u0435\u043c \u0446\u0435\u043d\u0442\u0440\u0430\u043b\u044c\u043d\u0443\u044e \u0441\u0442\u0440\u0435\u043b\u043a\u0443 \u0432 \u043e\u043a\u0440\u0443\u0436\u0435\u043d\u0438\u0438 \u0434\u0440\u0443\u0433\u0438\u0445 \u0441\u0442\u0440\u0435\u043b\u043e\u043a, \u0438 \u043d\u0430\u0436\u0438\u043c\u0430\u0435\u0442\u0435 \u0432\u043b\u0435\u0432\u043e \u0438\u043b\u0438 \u0432\u043f\u0440\u0430\u0432\u043e \u0442\u043e\u043b\u044c\u043a\u043e \u043f\u043e \u043d\u0430\u043f\u0440\u0430\u0432\u043b\u0435\u043d\u0438\u044e \u0441\u0440\u0435\u0434\u043d\u0435\u0439 \u0441\u0442\u0440\u0435\u043b\u043a\u0438, \u0438\u0433\u043d\u043e\u0440\u0438\u0440\u0443\u044f \u0441\u043e\u0441\u0435\u0434\u043d\u0438\u0435. \u0421\u0440\u0430\u0432\u043d\u0438\u0432\u0430\u044f \u0432\u0430\u0448\u0435 \u0432\u0440\u0435\u043c\u044f \u0440\u0435\u0430\u043a\u0446\u0438\u0438 \u043f\u0440\u0438 \u0440\u0430\u0437\u043d\u044b\u0445 \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u043a\u0430\u0445 \u0438 \u0440\u0430\u0437\u043d\u043e\u043c \u043e\u043a\u0440\u0443\u0436\u0435\u043d\u0438\u0438, \u0442\u0435\u0441\u0442 \u043f\u043e \u043e\u0442\u0434\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u0438 \u043e\u0446\u0435\u043d\u0438\u0432\u0430\u0435\u0442 \u0442\u0440\u0438 \u0432\u0435\u0449\u0438: \u0431\u0434\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c, \u043e\u0440\u0438\u0435\u043d\u0442\u0438\u0440\u043e\u0432\u043a\u0443 \u0438 \u043f\u043e\u0434\u0430\u0432\u043b\u0435\u043d\u0438\u0435 \u043f\u043e\u043c\u0435\u0445\u0438.",benefit:"\u0422\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u0438\u0437\u0431\u0438\u0440\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0435 \u0438 \u0443\u043f\u0440\u0430\u0432\u043b\u044f\u044e\u0449\u0435\u0435 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u2014 \u043f\u0440\u0435\u0436\u0434\u0435 \u0432\u0441\u0435\u0433\u043e \u0443\u043c\u0435\u043d\u0438\u0435 \u0443\u0434\u0435\u0440\u0436\u0430\u0442\u044c \u0446\u0435\u043b\u044c \u0438 \u043e\u0442\u0441\u0435\u0447\u044c \u043e\u0442\u0432\u043b\u0435\u043a\u0430\u044e\u0449\u0435\u0435 \u043e\u043a\u0440\u0443\u0436\u0435\u043d\u0438\u0435, \u0430 \u0442\u0430\u043a\u0436\u0435 \u0433\u043e\u0442\u043e\u0432\u043d\u043e\u0441\u0442\u044c \u043a \u0441\u0438\u0433\u043d\u0430\u043b\u0443 \u0438 \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u0443\u044e \u043e\u0440\u0438\u0435\u043d\u0442\u0438\u0440\u043e\u0432\u043a\u0443 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f.",history:"\u0422\u0435\u0441\u0442 \u0432\u044b\u0440\u043e\u0441 \u0438\u0437 \u0434\u0435\u0441\u044f\u0442\u0438\u043b\u0435\u0442\u0438\u0439 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u0439 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f \u0438 \u0431\u044b\u043b \u043e\u043f\u0443\u0431\u043b\u0438\u043a\u043e\u0432\u0430\u043d \u043a\u0430\u043a \u0435\u0434\u0438\u043d\u0430\u044f \u043e\u0431\u044a\u0435\u0434\u0438\u043d\u0451\u043d\u043d\u0430\u044f \u0437\u0430\u0434\u0430\u0447\u0430 \u0432 2002 \u0433\u043e\u0434\u0443, \u0441\u043e\u0435\u0434\u0438\u043d\u0438\u0432 \u0434\u0432\u0435 \u043a\u043b\u0430\u0441\u0441\u0438\u043a\u0438: \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u0443\u044e \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u043a\u0443 \u041f\u043e\u0437\u043d\u0435\u0440\u0430 \u0438 \u0444\u043b\u0430\u043d\u043a\u0435\u0440-\u0437\u0430\u0434\u0430\u0447\u0443 \u042d\u0440\u0438\u043a\u0441\u0435\u043d\u0430. \u041e\u043d \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u0439, \u043d\u0435 \u0442\u0440\u0435\u0431\u0443\u0435\u0442 \u044f\u0437\u044b\u043a\u0430 \u0438 \u043f\u043e\u0434\u0445\u043e\u0434\u0438\u0442 \u0434\u0435\u0442\u044f\u043c, \u043f\u0430\u0446\u0438\u0435\u043d\u0442\u0430\u043c \u0438 \u0434\u0430\u0436\u0435 \u043e\u0431\u0435\u0437\u044c\u044f\u043d\u0430\u043c, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u0431\u044b\u0441\u0442\u0440\u043e \u0440\u0430\u0437\u043e\u0448\u0451\u043b\u0441\u044f \u043f\u043e \u043b\u0430\u0431\u043e\u0440\u0430\u0442\u043e\u0440\u0438\u044f\u043c \u043a\u043e\u0433\u043d\u0438\u0442\u0438\u0432\u043d\u043e\u0439 \u043d\u0435\u0439\u0440\u043e\u043d\u0430\u0443\u043a\u0438, \u0444\u041c\u0420\u0422 \u0438 \u0433\u0435\u043d\u0435\u0442\u0438\u043a\u0438 \u0438 \u0442\u0435\u043f\u0435\u0440\u044c \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u0432\u043e \u043c\u043d\u043e\u0436\u0435\u0441\u0442\u0432\u0435 \u043f\u0435\u0440\u0435\u0440\u0430\u0431\u043e\u0442\u0430\u043d\u043d\u044b\u0445 \u0432\u0435\u0440\u0441\u0438\u0439.",creator:"\u0422\u0435\u0441\u0442 \u0432\u043d\u0438\u043c\u0430\u0442\u0435\u043b\u044c\u043d\u044b\u0445 \u0441\u0435\u0442\u0435\u0439 \u0441\u043e\u0437\u0434\u0430\u043b\u0438 \u0426\u0437\u0438\u043d\u044c \u0424\u0430\u043d\u044c, \u0411\u0440\u044e\u0441 \u041c\u0430\u043a-\u041a\u044d\u043d\u0434\u043b\u0438\u0441\u0441, \u0422\u043e\u0431\u0438\u0430\u0441 \u0417\u043e\u043c\u043c\u0435\u0440, \u0410\u043c\u0438\u0440 \u0420\u0430\u0437 \u0438 \u041c\u0430\u0439\u043a\u043b \u041f\u043e\u0437\u043d\u0435\u0440; \u0440\u0430\u0431\u043e\u0442\u0430 \u0432\u044b\u0448\u043b\u0430 \u0432 2002 \u0433\u043e\u0434\u0443 \u0432 Journal of Cognitive Neuroscience. \u041e\u043d \u043f\u0435\u0440\u0435\u0432\u0451\u043b \u0432 \u0438\u0437\u043c\u0435\u0440\u0438\u043c\u0443\u044e \u0444\u043e\u0440\u043c\u0443 \u043c\u043e\u0434\u0435\u043b\u044c \u0442\u0440\u0451\u0445 \u0441\u0435\u0442\u0435\u0439 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f, \u043a\u043e\u0442\u043e\u0440\u0443\u044e \u041f\u043e\u0437\u043d\u0435\u0440 \u0438 \u041f\u0435\u0442\u0435\u0440\u0441\u0435\u043d \u043f\u0440\u0435\u0434\u043b\u043e\u0436\u0438\u043b\u0438 \u0435\u0449\u0451 \u0432 1990 \u0433\u043e\u0434\u0443.",methods:"\u0414\u0435\u0440\u0436\u0438\u0442\u0435 \u0432\u0437\u0433\u043b\u044f\u0434 \u043d\u0430 \u0446\u0435\u043d\u0442\u0440\u0430\u043b\u044c\u043d\u043e\u0439 \u0442\u043e\u0447\u043a\u0435 \u0438 \u0440\u0435\u0430\u0433\u0438\u0440\u0443\u0439\u0442\u0435 \u0442\u043e\u043b\u044c\u043a\u043e \u043d\u0430 \u0441\u0440\u0435\u0434\u043d\u044e\u044e \u0441\u0442\u0440\u0435\u043b\u043a\u0443, \u043d\u0438\u043a\u043e\u0433\u0434\u0430 \u2014 \u043d\u0430 \u0441\u043e\u0441\u0435\u0434\u043d\u0438\u0435. \u0421\u043d\u0430\u0447\u0430\u043b\u0430 \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u044c, \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u043f\u0440\u0438\u0434\u0451\u0442 \u0441\u0430\u043c\u0430: \u0441\u043f\u0435\u0448\u043a\u0430 \u0440\u0430\u0437\u0434\u0443\u0432\u0430\u0435\u0442 \u043e\u0448\u0438\u0431\u043a\u0438 \u0438\u043c\u0435\u043d\u043d\u043e \u043d\u0430 \u043f\u0440\u043e\u0431\u0430\u0445 \u0441 \u043a\u043e\u043d\u0444\u043b\u0438\u043a\u0442\u043e\u043c. \u041d\u0435 \u0443\u0433\u0430\u0434\u044b\u0432\u0430\u0439\u0442\u0435 \u0441\u0442\u043e\u0440\u043e\u043d\u0443 \u0437\u0430\u0440\u0430\u043d\u0435\u0435 \u2014 \u043f\u0443\u0441\u0442\u044c \u0435\u0451 \u043f\u043e\u0434\u0441\u043a\u0430\u0436\u0435\u0442 \u0441\u0442\u0440\u0435\u043b\u043a\u0430, \u0430 \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u043a\u0443 \u0432\u043e\u0441\u043f\u0440\u0438\u043d\u0438\u043c\u0430\u0439\u0442\u0435 \u043b\u0438\u0448\u044c \u043a\u0430\u043a \u0441\u0438\u0433\u043d\u0430\u043b \xab\u0441\u0435\u0439\u0447\u0430\u0441 \u0447\u0442\u043e-\u0442\u043e \u0431\u0443\u0434\u0435\u0442\xbb.",duration:"\u041f\u043e\u043b\u043d\u044b\u0439 \u043f\u0440\u043e\u0433\u043e\u043d \u0437\u0430\u043d\u0438\u043c\u0430\u0435\u0442 \u043f\u0440\u0438\u043c\u0435\u0440\u043d\u043e 20\u201330 \u043c\u0438\u043d\u0443\u0442 \u2014 \u044d\u0442\u043e \u0431\u043e\u043b\u044c\u0448\u0435, \u0447\u0435\u043c \u043b\u0451\u0433\u043a\u0430\u044f \u0435\u0436\u0435\u0434\u043d\u0435\u0432\u043d\u0430\u044f \u0440\u0430\u0437\u043c\u0438\u043d\u043a\u0430. \u041a\u043e\u0440\u043e\u0442\u043a\u0438\u0445 \u0441\u0435\u0441\u0441\u0438\u0439 \u043f\u043e 10\u201315 \u043c\u0438\u043d\u0443\u0442 \u043f\u0430\u0440\u0443-\u0442\u0440\u043e\u0439\u043a\u0443 \u0440\u0430\u0437 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e \u0434\u043e\u0441\u0442\u0430\u0442\u043e\u0447\u043d\u043e, \u0447\u0442\u043e\u0431\u044b \u0434\u0435\u0440\u0436\u0430\u0442\u044c \u0444\u043e\u0440\u043c\u0443 \u0432 \u0441\u0430\u043c\u043e\u0439 \u0437\u0430\u0434\u0430\u0447\u0435; \u0434\u0430\u043d\u043d\u044b\u0445, \u0447\u0442\u043e \u043c\u043d\u043e\u0433\u043e\u0447\u0430\u0441\u043e\u0432\u0430\u044f \u0437\u0443\u0431\u0440\u0451\u0436\u043a\u0430 \u0447\u0442\u043e-\u0442\u043e \u0434\u043e\u0431\u0430\u0432\u043b\u044f\u0435\u0442, \u043d\u0435\u0442.",research:"\u0414\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u043d\u0435\u0435 \u0432\u0441\u0435\u0433\u043e \u0440\u043e\u0432\u043d\u043e \u0442\u043e, \u0447\u0435\u0433\u043e \u0438 \u0436\u0434\u0451\u0448\u044c: \u0441 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u043e\u0439 \u0432\u044b \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u0438 \u0441\u0442\u0430\u0431\u0438\u043b\u044c\u043d\u0435\u0435 \u0438\u043c\u0435\u043d\u043d\u043e \u0432 \u044d\u0442\u043e\u0439 \u0437\u0430\u0434\u0430\u0447\u0435 \u0441\u043e \u0441\u0442\u0440\u0435\u043b\u043a\u0430\u043c\u0438 \u0438 \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u043a\u043e\u0439, \u0430 \u043f\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c \u043a\u043e\u043d\u0444\u043b\u0438\u043a\u0442\u0430 (\u0443\u043f\u0440\u0430\u0432\u043b\u044f\u044e\u0449\u0438\u0439 \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044c) \u043e\u0442 \u0441\u0435\u0441\u0441\u0438\u0438 \u043a \u0441\u0435\u0441\u0441\u0438\u0438 \u0434\u0435\u0440\u0436\u0438\u0442\u0441\u044f \u043d\u0435\u043f\u043b\u043e\u0445\u043e. \u0417\u0430\u0433\u0432\u043e\u0437\u0434\u043a\u0430 \u0432 \u043f\u0441\u0438\u0445\u043e\u043c\u0435\u0442\u0440\u0438\u043a\u0435: \u043f\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u0438 \u0431\u0434\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u0438 \u0438 \u043e\u0440\u0438\u0435\u043d\u0442\u0438\u0440\u043e\u0432\u043a\u0438 \u0448\u0443\u043c\u043d\u044b\u0435 \u0438 \u043f\u043b\u043e\u0445\u043e \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u044f\u0442\u0441\u044f \u043c\u0435\u0436\u0434\u0443 \u0437\u0430\u043c\u0435\u0440\u0430\u043c\u0438, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u043f\u043e \u043e\u0434\u043d\u043e\u043c\u0443 \u0438\u0437\u043c\u0435\u0440\u0435\u043d\u0438\u044e \u043e \u043d\u0438\u0445 \u0441\u0443\u0434\u0438\u0442\u044c \u043d\u0435\u043b\u044c\u0437\u044f. \u0423\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043d\u0438\u044f, \u0447\u0442\u043e \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0430 ANT \u0440\u0430\u0441\u0448\u0438\u0440\u044f\u0435\u0442 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u0432 \u0446\u0435\u043b\u043e\u043c, \u043f\u043e\u0434\u043d\u0438\u043c\u0430\u0435\u0442 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0438\u043b\u0438 \u043e\u0442\u043e\u0434\u0432\u0438\u0433\u0430\u0435\u0442 \u043a\u043e\u0433\u043d\u0438\u0442\u0438\u0432\u043d\u044b\u0439 \u0441\u043f\u0430\u0434, \u043d\u0435 \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043d\u044b \u2014 \u043a \u0433\u0440\u043e\u043c\u043a\u0438\u043c \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f\u043c \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u0435\u0441\u044c \u0441 \u043e\u0441\u0442\u043e\u0440\u043e\u0436\u043d\u043e\u0441\u0442\u044c\u044e.",rec:"\u0418\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0439\u0442\u0435 \u0435\u0433\u043e \u043a\u0430\u043a \u0441\u0444\u043e\u043a\u0443\u0441\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u0443\u044e \u0440\u0430\u0437\u043c\u0438\u043d\u043a\u0443: \u043e\u0434\u0438\u043d \u0447\u0438\u0441\u0442\u044b\u0439 \u043f\u0440\u043e\u0433\u043e\u043d \u0441 \u0444\u0438\u043a\u0441\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u044b\u043c \u0432\u0437\u0433\u043b\u044f\u0434\u043e\u043c \u0438 \u0443\u043f\u043e\u0440\u043e\u043c \u043d\u0430 \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u044c, \u0430 \u043d\u0435 \u0434\u0435\u0441\u044f\u0442\u043e\u043a \u043d\u0435\u0431\u0440\u0435\u0436\u043d\u044b\u0445 \u0437\u0430\u0431\u0435\u0433\u043e\u0432 \u043d\u0430 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c.",faq:[["\u0427\u0442\u043e \u043d\u0430 \u0441\u0430\u043c\u043e\u043c \u0434\u0435\u043b\u0435 \u043e\u0437\u043d\u0430\u0447\u0430\u044e\u0442 \u0442\u0440\u0438 \u043f\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044f?","\u041a\u0430\u0436\u0434\u044b\u0439 \u2014 \u044d\u0442\u043e \u0440\u0430\u0437\u043d\u0438\u0446\u0430 \u0432\u043e \u0432\u0440\u0435\u043c\u0435\u043d\u0438 \u0440\u0435\u0430\u043a\u0446\u0438\u0438: \u0431\u0434\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c \u043f\u043e\u043a\u0430\u0437\u044b\u0432\u0430\u0435\u0442, \u043d\u0430\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0432\u0430\u0441 \u0443\u0441\u043a\u043e\u0440\u044f\u0435\u0442 \u043f\u0440\u0435\u0434\u0443\u043f\u0440\u0435\u0436\u0434\u0430\u044e\u0449\u0430\u044f \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u043a\u0430, \u043e\u0440\u0438\u0435\u043d\u0442\u0438\u0440\u043e\u0432\u043a\u0430 \u2014 \u0432\u044b\u0438\u0433\u0440\u044b\u0448 \u043e\u0442 \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u043a\u0438, \u0443\u043a\u0430\u0437\u044b\u0432\u0430\u044e\u0449\u0435\u0439 \u043c\u0435\u0441\u0442\u043e \u0446\u0435\u043b\u0438, \u0430 \u0443\u043f\u0440\u0430\u0432\u043b\u044f\u044e\u0449\u0438\u0439 \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044c \u2014 \u043d\u0430\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0432\u0430\u0441 \u0437\u0430\u043c\u0435\u0434\u043b\u044f\u044e\u0442 \u043a\u043e\u043d\u0444\u043b\u0438\u043a\u0442\u0443\u044e\u0449\u0438\u0435 \u0441\u043e\u0441\u0435\u0434\u043d\u0438\u0435 \u0441\u0442\u0440\u0435\u043b\u043a\u0438."],["\u041d\u0430\u0434\u0451\u0436\u043d\u043e \u043b\u0438 ANT \u0438\u0437\u043c\u0435\u0440\u044f\u0435\u0442 \u043c\u043e\u0451 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435?","\u041e\u0442\u0447\u0430\u0441\u0442\u0438. \u041f\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c \u0443\u043f\u0440\u0430\u0432\u043b\u044f\u044e\u0449\u0435\u0433\u043e \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044f (\u043a\u043e\u043d\u0444\u043b\u0438\u043a\u0442\u0430) \u0434\u043e\u0432\u043e\u043b\u044c\u043d\u043e \u0441\u0442\u0430\u0431\u0438\u043b\u0435\u043d, \u0430 \u0432\u043e\u0442 \u043f\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u0438 \u0431\u0434\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u0438 \u0438 \u043e\u0440\u0438\u0435\u043d\u0442\u0438\u0440\u043e\u0432\u043a\u0438 \u0441\u0442\u0430\u0442\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043a\u0438 \u0448\u0443\u043c\u043d\u044b\u0435, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u043d\u0435 \u0441\u0442\u043e\u0438\u0442 \u0434\u0435\u043b\u0430\u0442\u044c \u0432\u044b\u0432\u043e\u0434\u043e\u0432 \u043f\u043e \u043e\u0434\u043d\u043e\u043c\u0443 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442\u0443, \u043e\u0441\u043e\u0431\u0435\u043d\u043d\u043e \u043f\u043e \u044d\u0442\u0438\u043c \u0434\u0432\u0443\u043c."],["\u0421\u0434\u0435\u043b\u0430\u0435\u0442 \u043b\u0438 \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0430 ANT \u043c\u0435\u043d\u044f \u0432\u043d\u0438\u043c\u0430\u0442\u0435\u043b\u044c\u043d\u0435\u0435 \u0432 \u0436\u0438\u0437\u043d\u0438?","\u0412 \u0441\u0430\u043c\u043e\u043c ANT \u0432\u044b \u0437\u0430\u043c\u0435\u0442\u043d\u043e \u043f\u0440\u0438\u0431\u0430\u0432\u0438\u0442\u0435, \u043d\u043e \u0448\u0438\u0440\u043e\u043a\u043e\u0433\u043e \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0430 \u043d\u0430 \u043f\u043e\u0432\u0441\u0435\u0434\u043d\u0435\u0432\u043d\u0443\u044e \u043a\u043e\u043d\u0446\u0435\u043d\u0442\u0440\u0430\u0446\u0438\u044e \u044d\u0442\u043e \u043d\u0435 \u0433\u0430\u0440\u0430\u043d\u0442\u0438\u0440\u0443\u0435\u0442. \u0421\u0447\u0438\u0442\u0430\u0439\u0442\u0435 \u0435\u0433\u043e \u0442\u043e\u0447\u0435\u0447\u043d\u043e\u0439 \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u043e\u0439, \u0430 \u043d\u0435 \u0432\u0435\u0440\u043d\u044b\u043c \u0430\u043f\u0433\u0440\u0435\u0439\u0434\u043e\u043c \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f \u0432 \u0446\u0435\u043b\u043e\u043c."]],variants:"\u0421\u0440\u0435\u0434\u0438 \u0440\u0430\u0441\u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0451\u043d\u043d\u044b\u0445 \u0432\u0435\u0440\u0441\u0438\u0439 \u2014 \u0434\u0435\u0442\u0441\u043a\u0430\u044f (\u0441 \u0440\u044b\u0431\u043a\u0430\u043c\u0438), ANT-R (\u043f\u0435\u0440\u0435\u0440\u0430\u0431\u043e\u0442\u0430\u043d\u043d\u0430\u044f) \u0441 \u0434\u043e\u043f\u043e\u043b\u043d\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u043c\u0438 \u0438\u043d\u0442\u0435\u0440\u0432\u0430\u043b\u0430\u043c\u0438 \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u043a\u0438 \u0438 \u0444\u043b\u0430\u043d\u043a\u0435\u0440\u043e\u0432 \u0434\u043b\u044f \u043f\u0440\u043e\u0432\u0435\u0440\u043a\u0438 \u0432\u0437\u0430\u0438\u043c\u043e\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044f \u0441\u0435\u0442\u0435\u0439, ANTI-V \u0441 \u0434\u043e\u0431\u0430\u0432\u043b\u0435\u043d\u043d\u044b\u043c \u043a\u043e\u043c\u043f\u043e\u043d\u0435\u043d\u0442\u043e\u043c \u0443\u0441\u0442\u043e\u0439\u0447\u0438\u0432\u043e\u0433\u043e \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f (\u0432\u0438\u0433\u0438\u043b\u044c\u043d\u043e\u0441\u0442\u0438) \u0438 \u043b\u0430\u0442\u0435\u0440\u0430\u043b\u0438\u0437\u043e\u0432\u0430\u043d\u043d\u044b\u0435 \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u044b, \u0433\u0434\u0435 \u0446\u0435\u043b\u044c \u043f\u043e\u043a\u0430\u0437\u044b\u0432\u0430\u044e\u0442 \u0432 \u043e\u0434\u043d\u043e\u043c \u043f\u043e\u043b\u0435 \u0437\u0440\u0435\u043d\u0438\u044f."},en:{about:"ANT is a cued arrow task. On each trial you wait for a fixation cross, sometimes see a cue (a flash above or below where the target will appear), then a central arrow flanked by other arrows, and you press left or right depending only on which way the centre arrow points while ignoring its neighbours. By comparing your reaction times across cue types and flanker types, the test estimates three things separately: alerting, orienting, and resolving conflict.",benefit:"It exercises selective and executive attention, in particular the ability to lock onto a target and suppress distracting information around it, plus the readiness and spatial-orienting side of attention.",history:"It grew out of decades of attention research and was published as a single combined task in 2002, fusing two classic paradigms: Posner's spatial cueing and the Eriksen flanker task. Because it is short, language-free and works with children, patients and even monkeys, it spread quickly through cognitive neuroscience, fMRI and genetics labs and now exists in many revised forms.",creator:"The Attention Network Test was created by Jin Fan, Bruce McCandliss, Tobias Sommer, Amir Raz and Michael Posner, published in 2002 in the Journal of Cognitive Neuroscience. It operationalised the three-network model of attention that Posner and Petersen had proposed in 1990.",methods:"Keep your eyes on the central fixation point and respond only to the middle arrow, never to the flankers. Aim for accuracy first and let speed come with it, because rushing inflates errors on the conflict trials. Don't pre-guess the side; let the arrow tell you, and treat the cue only as a 'something is about to happen' signal.",duration:"A full run is roughly 20 to 30 minutes, which is more than a casual daily drill. Short sessions of 10 to 15 minutes a few times a week are enough to stay sharp on the task; there is no evidence that grinding it for hours adds anything.",research:"Evidence is strongest for exactly what you would expect: with practice you get faster and more consistent on this specific cued-flanker task, and the conflict (executive) score is reasonably stable from session to session. The catch is psychometric: the alerting and orienting difference scores are noisy and replicate poorly between sittings, so single readings of them mean little. Claims that training ANT widens general attention, boosts intelligence or holds off cognitive decline are not established, so treat the grand promises with caution.",rec:"Use it as a focused warm-up: one clean run with your gaze fixed and your eyes on accuracy, rather than many sloppy speed runs.",faq:[["What do the three scores actually mean?","Each is a difference in reaction time: alerting is how much a warning cue speeds you up, orienting is the benefit of a cue that shows where the target will be, and executive control is how much the conflicting flankers slow you down."],["Is the ANT a reliable measure of my attention?","Partly. The executive-control (conflict) score is fairly stable, but the alerting and orienting scores are statistically noisy, so don't over-read a single result, especially for those two."],["Will training on the ANT make me more attentive in daily life?","You will clearly improve at the ANT itself, but broad carry-over to everyday focus is not proven. Treat it as targeted practice, not a guaranteed upgrade to your general attention."]],variants:"Common variants include the child (fish) version, the ANT-R (revised) with extra cue and flanker timings to probe network interactions, the Attention Network Test for Interactions and Vigilance (ANTI-V) that adds a sustained-attention component, and lateralised versions that present targets to one visual field."},es:{about:"El ANT es una tarea de flechas con se\xf1al. En cada ensayo esperas a una cruz de fijaci\xf3n, a veces ves una se\xf1al (un destello encima o debajo de donde aparecer\xe1 el objetivo) y luego una flecha central flanqueada por otras flechas, y pulsas izquierda o derecha seg\xfan hacia d\xf3nde apunta \xfanicamente la flecha central, ignorando a sus vecinas. Al comparar tus tiempos de reacci\xf3n entre tipos de se\xf1al y tipos de flancos, la prueba estima por separado tres cosas: la alerta, la orientaci\xf3n y la resoluci\xf3n del conflicto.",benefit:"Ejercita la atenci\xf3n selectiva y ejecutiva, en particular la capacidad de fijarte en un objetivo y suprimir la informaci\xf3n distractora a su alrededor, adem\xe1s del lado de la preparaci\xf3n y la orientaci\xf3n espacial de la atenci\xf3n.",history:"Surgi\xf3 de d\xe9cadas de investigaci\xf3n sobre la atenci\xf3n y se public\xf3 como una \xfanica tarea combinada en 2002, fusionando dos paradigmas cl\xe1sicos: la se\xf1alizaci\xf3n espacial de Posner y la tarea de flancos de Eriksen. Por ser breve, no depender del idioma y funcionar con ni\xf1os, pacientes e incluso monos, se extendi\xf3 r\xe1pidamente por los laboratorios de neurociencia cognitiva, fMRI y gen\xe9tica, y hoy existe en muchas formas revisadas.",creator:"El Test de Redes Atencionales lo crearon Jin Fan, Bruce McCandliss, Tobias Sommer, Amir Raz y Michael Posner, y se public\xf3 en 2002 en el Journal of Cognitive Neuroscience. Puso en pr\xe1ctica el modelo de tres redes de la atenci\xf3n que Posner y Petersen hab\xedan propuesto en 1990.",methods:"Mant\xe9n la mirada en el punto de fijaci\xf3n central y responde solo a la flecha del medio, nunca a las de los flancos. Apunta primero a la exactitud y deja que la velocidad llegue por s\xed sola, porque ir con prisas dispara los errores en los ensayos de conflicto. No adivines el lado de antemano; deja que la flecha te lo diga y trata la se\xf1al solo como un aviso de que 'algo va a pasar'.",duration:"Una pasada completa dura unos 20 a 30 minutos, lo que es m\xe1s que un ejercicio diario informal. Sesiones cortas de 10 a 15 minutos algunas veces por semana bastan para mantenerte fino en la tarea; no hay evidencia de que machacarla durante horas aporte nada.",research:"La evidencia es m\xe1s s\xf3lida justo en lo que cabr\xeda esperar: con la pr\xe1ctica te vuelves m\xe1s r\xe1pido y constante en esta tarea concreta de flancos con se\xf1al, y la puntuaci\xf3n de conflicto (ejecutiva) es razonablemente estable de una sesi\xf3n a otra. La pega es psicom\xe9trica: las puntuaciones de diferencia de alerta y orientaci\xf3n son ruidosas y se replican mal entre sesiones, as\xed que sus lecturas aisladas significan poco. Las afirmaciones de que entrenar el ANT ampl\xeda la atenci\xf3n general, eleva la inteligencia o frena el deterioro cognitivo no est\xe1n establecidas, as\xed que toma con cautela las grandes promesas.",rec:"\xdasalo como calentamiento concentrado: una pasada limpia con la mirada fija y la vista puesta en la exactitud, en lugar de muchas pasadas r\xe1pidas y descuidadas.",faq:[["\xbfQu\xe9 significan en realidad las tres puntuaciones?","Cada una es una diferencia de tiempo de reacci\xf3n: la alerta es cu\xe1nto te acelera una se\xf1al de aviso, la orientaci\xf3n es el beneficio de una se\xf1al que indica d\xf3nde estar\xe1 el objetivo, y el control ejecutivo es cu\xe1nto te frenan los flancos en conflicto."],["\xbfEs el ANT una medida fiable de mi atenci\xf3n?","En parte. La puntuaci\xf3n de control ejecutivo (conflicto) es bastante estable, pero las de alerta y orientaci\xf3n son estad\xedsticamente ruidosas, as\xed que no sobreinterpretes un solo resultado, sobre todo en esas dos."],["\xbfEntrenar con el ANT me har\xe1 m\xe1s atento en el d\xeda a d\xeda?","Mejorar\xe1s con claridad en el propio ANT, pero el traslado amplio a la concentraci\xf3n cotidiana no est\xe1 demostrado. T\xf3malo como pr\xe1ctica dirigida, no como una mejora garantizada de tu atenci\xf3n general."]],variants:"Entre las variantes habituales est\xe1n la versi\xf3n infantil (de peces), el ANT-R (revisado) con tiempos extra de se\xf1al y flancos para sondear las interacciones entre redes, el Test de Redes Atencionales para Interacciones y Vigilancia (ANTI-V) que a\xf1ade un componente de atenci\xf3n sostenida, y las versiones lateralizadas que presentan los objetivos en un solo campo visual."},de:{about:"Der ANT ist eine Pfeilaufgabe mit Hinweisreiz. In jedem Durchgang wartest du auf ein Fixationskreuz, siehst manchmal einen Hinweis (ein Aufblitzen \xfcber oder unter der Stelle, an der das Ziel erscheinen wird), dann einen zentralen Pfeil, flankiert von weiteren Pfeilen, und dr\xfcckst links oder rechts \u2013 einzig danach, wohin der mittlere Pfeil zeigt, w\xe4hrend du seine Nachbarn ignorierst. Indem deine Reaktionszeiten \xfcber die Hinweis- und Flanker-Arten hinweg verglichen werden, sch\xe4tzt der Test drei Dinge getrennt: Alarmierung, Orientierung und Konfliktl\xf6sung.",benefit:"Er beansprucht die selektive und exekutive Aufmerksamkeit, insbesondere die F\xe4higkeit, ein Ziel zu fixieren und ablenkende Information ringsum zu unterdr\xfccken, dazu die Bereitschafts- und die r\xe4umliche Orientierungsseite der Aufmerksamkeit.",history:"Er ging aus jahrzehntelanger Aufmerksamkeitsforschung hervor und wurde 2002 als eine einzige kombinierte Aufgabe ver\xf6ffentlicht, die zwei klassische Paradigmen verschmilzt: Posners r\xe4umliche Hinweisgebung und die Eriksen-Flanker-Aufgabe. Weil er kurz und sprachfrei ist und mit Kindern, Patienten und sogar Affen funktioniert, verbreitete er sich rasch durch die kognitive Neurowissenschaft sowie fMRT- und Genetiklabore und existiert heute in vielen \xfcberarbeiteten Formen.",creator:"Der Attention Network Test wurde von Jin Fan, Bruce McCandliss, Tobias Sommer, Amir Raz und Michael Posner entwickelt und 2002 im Journal of Cognitive Neuroscience ver\xf6ffentlicht. Er machte das Drei-Netzwerk-Modell der Aufmerksamkeit operationalisierbar, das Posner und Petersen 1990 vorgeschlagen hatten.",methods:"Halte die Augen auf dem zentralen Fixationspunkt und reagiere nur auf den mittleren Pfeil, niemals auf die Flanker. Strebe zuerst nach Genauigkeit und lass die Geschwindigkeit von selbst kommen, denn Hetzen bl\xe4ht die Fehler in den Konfliktdurchg\xe4ngen auf. Rate die Seite nicht vorweg; lass den Pfeil es dir sagen, und behandle den Hinweis nur als Signal \u201egleich passiert etwas\u201c.",duration:"Ein vollst\xe4ndiger Durchlauf dauert ungef\xe4hr 20 bis 30 Minuten, was mehr ist als eine beil\xe4ufige t\xe4gliche \xdcbung. Kurze Sitzungen von 10 bis 15 Minuten, ein paar Mal pro Woche, reichen aus, um in der Aufgabe ge\xfcbt zu bleiben; es gibt keinen Beleg, dass stundenlanges Schinden etwas hinzuf\xfcgt.",research:"Die Belege sind am st\xe4rksten f\xfcr genau das, was man erwarten w\xfcrde: Mit \xdcbung wirst du in dieser konkreten Hinweis-Flanker-Aufgabe schneller und gleichm\xe4\xdfiger, und der Konflikt-Wert (exekutiv) ist von Sitzung zu Sitzung einigerma\xdfen stabil. Der Haken ist psychometrisch: Die Differenzwerte f\xfcr Alarmierung und Orientierung sind verrauscht und replizieren zwischen Sitzungen schlecht, sodass Einzelmessungen davon wenig bedeuten. Behauptungen, ein ANT-Training erweitere die allgemeine Aufmerksamkeit, steigere die Intelligenz oder halte den kognitiven Abbau auf, sind nicht belegt \u2013 begegne den gro\xdfen Versprechen also mit Vorsicht.",rec:"Nutze ihn als fokussiertes Aufw\xe4rmen: ein sauberer Durchlauf mit fixiertem Blick und dem Auge auf Genauigkeit, statt vieler schludriger Geschwindigkeitsdurchl\xe4ufe.",faq:[["Was bedeuten die drei Werte eigentlich?","Jeder ist eine Differenz in der Reaktionszeit: Alarmierung ist, wie sehr ein Warnhinweis dich beschleunigt, Orientierung ist der Vorteil eines Hinweises, der zeigt, wo das Ziel sein wird, und exekutive Kontrolle ist, wie sehr die widerspr\xfcchlichen Flanker dich verlangsamen."],["Ist der ANT ein verl\xe4ssliches Ma\xdf f\xfcr meine Aufmerksamkeit?","Teilweise. Der Wert f\xfcr exekutive Kontrolle (Konflikt) ist recht stabil, aber die Werte f\xfcr Alarmierung und Orientierung sind statistisch verrauscht \u2013 \xfcberinterpretiere ein einzelnes Ergebnis daher nicht, besonders nicht bei diesen beiden."],["Macht mich ein Training im ANT im Alltag aufmerksamer?","Du wirst klar besser im ANT selbst, aber ein breiter \xdcbertrag auf die allt\xe4gliche Konzentration ist nicht bewiesen. Sieh es als gezielte \xdcbung, nicht als garantiertes Upgrade deiner allgemeinen Aufmerksamkeit."]],variants:"H\xe4ufige Varianten sind die Kinderversion (mit Fischen), der ANT-R (revidiert) mit zus\xe4tzlichen Hinweis- und Flanker-Zeitabl\xe4ufen, um Netzwerk-Wechselwirkungen zu untersuchen, der Attention Network Test for Interactions and Vigilance (ANTI-V), der eine Daueraufmerksamkeits-Komponente erg\xe4nzt, und lateralisierte Versionen, die Ziele in nur ein Sichtfeld pr\xe4sentieren."},pt:{about:"O ANT \xe9 uma tarefa de setas com pistas. Em cada tentativa voc\xea espera por uma cruz de fixa\xe7\xe3o, \xe0s vezes v\xea uma pista (um flash acima ou abaixo de onde o alvo vai aparecer) e depois uma seta central ladeada por outras setas, e pressiona esquerda ou direita apenas conforme a dire\xe7\xe3o da seta do meio, ignorando as vizinhas. Ao comparar os seus tempos de rea\xe7\xe3o entre tipos de pista e tipos de flanco, o teste estima tr\xeas coisas separadamente: alerta, orienta\xe7\xe3o e resolu\xe7\xe3o de conflito.",benefit:"Exercita a aten\xe7\xe3o seletiva e executiva, em particular a capacidade de fixar-se num alvo e suprimir a informa\xe7\xe3o distratora ao redor, al\xe9m do lado de prontid\xe3o e de orienta\xe7\xe3o espacial da aten\xe7\xe3o.",history:"Surgiu de d\xe9cadas de investiga\xe7\xe3o sobre a aten\xe7\xe3o e foi publicado como uma \xfanica tarefa combinada em 2002, fundindo dois paradigmas cl\xe1ssicos: a sinaliza\xe7\xe3o espacial de Posner e a tarefa de flancos de Eriksen. Por ser curto, livre de linguagem e funcionar com crian\xe7as, pacientes e at\xe9 macacos, espalhou-se rapidamente pelos laborat\xf3rios de neuroci\xeancia cognitiva, de fMRI e de gen\xe9tica, e existe hoje em muitas formas revistas.",creator:"O Attention Network Test foi criado por Jin Fan, Bruce McCandliss, Tobias Sommer, Amir Raz e Michael Posner, publicado em 2002 no Journal of Cognitive Neuroscience. Operacionalizou o modelo de tr\xeas redes da aten\xe7\xe3o que Posner e Petersen haviam proposto em 1990.",methods:"Mantenha os olhos no ponto de fixa\xe7\xe3o central e responda apenas \xe0 seta do meio, nunca aos flancos. Busque primeiro a precis\xe3o e deixe a velocidade vir com ela, porque ter pressa infla os erros nas tentativas de conflito. N\xe3o adivinhe o lado de antem\xe3o; deixe a seta dizer e trate a pista apenas como um sinal de 'algo est\xe1 prestes a acontecer'.",duration:"Uma execu\xe7\xe3o completa leva cerca de 20 a 30 minutos, o que \xe9 mais do que um exerc\xedcio di\xe1rio casual. Sess\xf5es curtas de 10 a 15 minutos, algumas vezes por semana, bastam para manter o bom desempenho na tarefa; n\xe3o h\xe1 evid\xeancia de que insistir nela durante horas acrescente algo.",research:"As evid\xeancias s\xe3o mais fortes exatamente para o que seria de esperar: com a pr\xe1tica voc\xea fica mais r\xe1pido e mais consistente nesta tarefa espec\xedfica de setas com pistas, e a pontua\xe7\xe3o de conflito (executiva) \xe9 razoavelmente est\xe1vel de uma sess\xe3o para outra. A ressalva \xe9 psicom\xe9trica: as pontua\xe7\xf5es de diferen\xe7a de alerta e de orienta\xe7\xe3o s\xe3o ruidosas e replicam-se mal entre sess\xf5es, por isso leituras isoladas delas significam pouco. Alega\xe7\xf5es de que treinar o ANT amplia a aten\xe7\xe3o geral, eleva a intelig\xeancia ou trava o decl\xednio cognitivo n\xe3o est\xe3o estabelecidas, ent\xe3o encare as grandes promessas com cautela.",rec:"Use-o como um aquecimento focado: uma execu\xe7\xe3o limpa, com o olhar fixo e a aten\xe7\xe3o na precis\xe3o, em vez de muitas execu\xe7\xf5es de velocidade desleixadas.",faq:[["O que significam de fato as tr\xeas pontua\xe7\xf5es?","Cada uma \xe9 uma diferen\xe7a no tempo de rea\xe7\xe3o: o alerta \xe9 o quanto uma pista de aviso acelera voc\xea, a orienta\xe7\xe3o \xe9 o benef\xedcio de uma pista que mostra onde o alvo vai aparecer, e o controle executivo \xe9 o quanto os flancos conflitantes atrasam voc\xea."],["O ANT \xe9 uma medida fi\xe1vel da minha aten\xe7\xe3o?","Em parte. A pontua\xe7\xe3o de controle executivo (conflito) \xe9 razoavelmente est\xe1vel, mas as de alerta e de orienta\xe7\xe3o s\xe3o estatisticamente ruidosas, ent\xe3o n\xe3o interprete demais um \xfanico resultado, sobretudo nessas duas."],["Treinar o ANT vai me deixar mais atento na vida di\xe1ria?","Voc\xea vai claramente melhorar no pr\xf3prio ANT, mas a transfer\xeancia ampla para o foco no dia a dia n\xe3o est\xe1 comprovada. Encare-o como pr\xe1tica direcionada, n\xe3o como uma melhoria garantida da sua aten\xe7\xe3o geral."]],variants:"As variantes comuns incluem a vers\xe3o infantil (peixes), o ANT-R (revisto), com tempos extra de pista e de flancos para sondar as intera\xe7\xf5es entre redes, o Attention Network Test for Interactions and Vigilance (ANTI-V), que acrescenta um componente de aten\xe7\xe3o sustentada, e vers\xf5es lateralizadas que apresentam os alvos a um dos campos visuais."},hi:{about:"ANT \u090f\u0915 \u0938\u0902\u0915\u0947\u0924-\u0938\u0939\u093f\u0924 \u0924\u0940\u0930 \u0935\u093e\u0932\u093e \u0915\u093e\u0930\u094d\u092f \u0939\u0948\u0964 \u0939\u0930 \u091f\u094d\u0930\u093e\u092f\u0932 \u092e\u0947\u0902 \u0906\u092a \u090f\u0915 \u092b\u093c\u093f\u0915\u094d\u0938\u0947\u0936\u0928 \u0915\u094d\u0930\u0949\u0938 \u0915\u093e \u0907\u0902\u0924\u091c\u093c\u093e\u0930 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902, \u0915\u092d\u0940 \u090f\u0915 \u0938\u0902\u0915\u0947\u0924 \u0926\u0947\u0916\u0924\u0947 \u0939\u0948\u0902 (\u091c\u0939\u093e\u0901 \u0932\u0915\u094d\u0937\u094d\u092f \u0906\u0928\u0947 \u0935\u093e\u0932\u093e \u0939\u0948 \u0909\u0938\u0915\u0947 \u090a\u092a\u0930 \u092f\u093e \u0928\u0940\u091a\u0947 \u090f\u0915 \u091a\u092e\u0915), \u092b\u093f\u0930 \u092c\u0940\u091a \u092e\u0947\u0902 \u090f\u0915 \u0924\u0940\u0930 \u091c\u093f\u0938\u0915\u0947 \u0926\u094b\u0928\u094b\u0902 \u0913\u0930 \u0914\u0930 \u0924\u0940\u0930 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u0906\u092a \u0938\u093f\u0930\u094d\u092b\u093c \u0907\u0938 \u0906\u0927\u093e\u0930 \u092a\u0930 \u092c\u093e\u092f\u093e\u0901 \u092f\u093e \u0926\u093e\u092f\u093e\u0901 \u0926\u092c\u093e\u0924\u0947 \u0939\u0948\u0902 \u0915\u093f \u092c\u0940\u091a \u0935\u093e\u0932\u093e \u0924\u0940\u0930 \u0915\u093f\u0938 \u0913\u0930 \u0907\u0936\u093e\u0930\u093e \u0915\u0930 \u0930\u0939\u093e \u0939\u0948 \u2014 \u092a\u0921\u093c\u094b\u0938\u0940 \u0924\u0940\u0930\u094b\u0902 \u0915\u094b \u0905\u0928\u0926\u0947\u0916\u093e \u0915\u0930\u0924\u0947 \u0939\u0941\u090f\u0964 \u0938\u0902\u0915\u0947\u0924 \u0915\u0947 \u092a\u094d\u0930\u0915\u093e\u0930\u094b\u0902 \u0914\u0930 \u0915\u093f\u0928\u093e\u0930\u0947 \u0935\u093e\u0932\u0947 \u0924\u0940\u0930\u094b\u0902 \u0915\u0947 \u092a\u094d\u0930\u0915\u093e\u0930\u094b\u0902 \u0915\u0947 \u092c\u0940\u091a \u0906\u092a\u0915\u0940 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0917\u0924\u093f \u0915\u0940 \u0924\u0941\u0932\u0928\u093e \u0915\u0930\u0915\u0947 \u092f\u0939 \u092a\u0930\u0940\u0915\u094d\u0937\u0923 \u0924\u0940\u0928 \u091a\u0940\u091c\u093c\u0947\u0902 \u0905\u0932\u0917-\u0905\u0932\u0917 \u0906\u0901\u0915\u0924\u093e \u0939\u0948: \u0938\u0924\u0930\u094d\u0915\u0924\u093e (alerting), \u0926\u093f\u0936\u093e-\u0928\u093f\u0930\u094d\u0927\u093e\u0930\u0923 (orienting), \u0914\u0930 \u091f\u0915\u0930\u093e\u0935 \u0938\u0941\u0932\u091d\u093e\u0928\u093e (conflict)\u0964",benefit:"\u092f\u0939 \u091a\u092f\u0928\u093e\u0924\u094d\u092e\u0915 \u0914\u0930 \u0915\u093e\u0930\u094d\u092f\u0915\u093e\u0930\u0940 \u0927\u094d\u092f\u093e\u0928 \u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0930\u093e\u0924\u093e \u0939\u0948 \u2014 \u0916\u093e\u0938\u0915\u0930 \u0915\u093f\u0938\u0940 \u0932\u0915\u094d\u0937\u094d\u092f \u092a\u0930 \u091f\u093f\u0915 \u091c\u093e\u0928\u0947 \u0914\u0930 \u0909\u0938\u0915\u0947 \u0907\u0930\u094d\u0926-\u0917\u093f\u0930\u094d\u0926 \u0915\u0940 \u092d\u091f\u0915\u093e\u0928\u0947 \u0935\u093e\u0932\u0940 \u091c\u093e\u0928\u0915\u093e\u0930\u0940 \u0915\u094b \u0926\u092c\u093e \u0926\u0947\u0928\u0947 \u0915\u0940 \u0915\u094d\u0937\u092e\u0924\u093e, \u0938\u093e\u0925 \u0939\u0940 \u0927\u094d\u092f\u093e\u0928 \u0915\u093e \u0924\u0924\u094d\u092a\u0930\u0924\u093e \u0914\u0930 \u0938\u094d\u0925\u093e\u0928\u093f\u0915 \u0926\u093f\u0936\u093e-\u0928\u093f\u0930\u094d\u0927\u093e\u0930\u0923 \u0935\u093e\u0932\u093e \u092a\u0939\u0932\u0942\u0964",history:"\u092f\u0939 \u0926\u0936\u0915\u094b\u0902 \u0915\u0947 \u0927\u094d\u092f\u093e\u0928-\u0905\u0928\u0941\u0938\u0902\u0927\u093e\u0928 \u0938\u0947 \u0928\u093f\u0915\u0932\u093e \u0914\u0930 2002 \u092e\u0947\u0902 \u090f\u0915 \u0905\u0915\u0947\u0932\u0947 \u0938\u0902\u092f\u0941\u0915\u094d\u0924 \u0915\u093e\u0930\u094d\u092f \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u092a\u094d\u0930\u0915\u093e\u0936\u093f\u0924 \u0939\u0941\u0906, \u091c\u093f\u0938\u092e\u0947\u0902 \u0926\u094b \u0915\u094d\u0932\u093e\u0938\u093f\u0915 \u092a\u094d\u0930\u0924\u093f\u092e\u093e\u0928\u094b\u0902 \u0915\u094b \u092e\u093f\u0932\u093e \u0926\u093f\u092f\u093e \u0917\u092f\u093e: Posner \u0915\u093e \u0938\u094d\u0925\u093e\u0928\u093f\u0915 \u0938\u0902\u0915\u0947\u0924\u0928 \u0914\u0930 Eriksen \u0915\u093e flanker \u0915\u093e\u0930\u094d\u092f\u0964 \u091a\u0942\u0901\u0915\u093f \u092f\u0939 \u091b\u094b\u091f\u093e, \u092d\u093e\u0937\u093e-\u0930\u0939\u093f\u0924 \u0939\u0948 \u0914\u0930 \u092c\u091a\u094d\u091a\u094b\u0902, \u092e\u0930\u0940\u091c\u093c\u094b\u0902 \u092f\u0939\u093e\u0901 \u0924\u0915 \u0915\u093f \u092c\u0902\u0926\u0930\u094b\u0902 \u0915\u0947 \u0938\u093e\u0925 \u092d\u0940 \u0915\u093e\u092e \u0915\u0930\u0924\u093e \u0939\u0948, \u092f\u0939 \u0938\u0902\u091c\u094d\u091e\u093e\u0928\u093e\u0924\u094d\u092e\u0915 \u0928\u094d\u092f\u0942\u0930\u094b\u0938\u093e\u0907\u0902\u0938, fMRI \u0914\u0930 \u091c\u0947\u0928\u0947\u091f\u093f\u0915\u094d\u0938 \u092a\u094d\u0930\u092f\u094b\u0917\u0936\u093e\u0932\u093e\u0913\u0902 \u092e\u0947\u0902 \u0924\u0947\u091c\u093c\u0940 \u0938\u0947 \u092b\u0948\u0932 \u0917\u092f\u093e \u0914\u0930 \u0905\u092c \u0915\u0908 \u0938\u0902\u0936\u094b\u0927\u093f\u0924 \u0930\u0942\u092a\u094b\u0902 \u092e\u0947\u0902 \u092e\u094c\u091c\u0942\u0926 \u0939\u0948\u0964",creator:"Attention Network Test \u0915\u094b Jin Fan, Bruce McCandliss, Tobias Sommer, Amir Raz \u0914\u0930 Michael Posner \u0928\u0947 \u092c\u0928\u093e\u092f\u093e, \u091c\u094b 2002 \u092e\u0947\u0902 Journal of Cognitive Neuroscience \u092e\u0947\u0902 \u092a\u094d\u0930\u0915\u093e\u0936\u093f\u0924 \u0939\u0941\u0906\u0964 \u0907\u0938\u0928\u0947 \u0927\u094d\u092f\u093e\u0928 \u0915\u0947 \u0909\u0938 \u0924\u0940\u0928-\u0928\u0947\u091f\u0935\u0930\u094d\u0915 \u092e\u0949\u0921\u0932 \u0915\u094b \u0935\u094d\u092f\u093e\u0935\u0939\u093e\u0930\u093f\u0915 \u0930\u0942\u092a \u0926\u093f\u092f\u093e \u091c\u093f\u0938\u0947 Posner \u0914\u0930 Petersen \u0928\u0947 1990 \u092e\u0947\u0902 \u092a\u094d\u0930\u0938\u094d\u0924\u093e\u0935\u093f\u0924 \u0915\u093f\u092f\u093e \u0925\u093e\u0964",methods:"\u0905\u092a\u0928\u0940 \u0906\u0901\u0916\u0947\u0902 \u092c\u0940\u091a \u0915\u0947 \u092b\u093c\u093f\u0915\u094d\u0938\u0947\u0936\u0928 \u092c\u093f\u0902\u0926\u0941 \u092a\u0930 \u091f\u093f\u0915\u093e\u090f \u0930\u0916\u0947\u0902 \u0914\u0930 \u0938\u093f\u0930\u094d\u092b\u093c \u092c\u0940\u091a \u0935\u093e\u0932\u0947 \u0924\u0940\u0930 \u092a\u0930 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0926\u0947\u0902, \u0915\u093f\u0928\u093e\u0930\u0947 \u0935\u093e\u0932\u0947 \u0924\u0940\u0930\u094b\u0902 \u092a\u0930 \u0915\u092d\u0940 \u0928\u0939\u0940\u0902\u0964 \u092a\u0939\u0932\u0947 \u0938\u091f\u0940\u0915\u0924\u093e \u0915\u093e \u0932\u0915\u094d\u0937\u094d\u092f \u0930\u0916\u0947\u0902 \u0914\u0930 \u0917\u0924\u093f \u0915\u094b \u0909\u0938\u0915\u0947 \u0938\u093e\u0925 \u0905\u092a\u0928\u0947-\u0906\u092a \u0906\u0928\u0947 \u0926\u0947\u0902, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u091c\u0932\u094d\u0926\u092c\u093e\u091c\u093c\u0940 \u091f\u0915\u0930\u093e\u0935 \u0935\u093e\u0932\u0947 \u091f\u094d\u0930\u093e\u092f\u0932 \u092e\u0947\u0902 \u0917\u0932\u0924\u093f\u092f\u093e\u0901 \u092c\u0922\u093c\u093e \u0926\u0947\u0924\u0940 \u0939\u0948\u0964 \u092a\u0939\u0932\u0947 \u0938\u0947 \u0905\u0902\u0926\u093e\u091c\u093c\u093e \u092e\u0924 \u0932\u0917\u093e\u0907\u090f \u0915\u093f \u0915\u094c\u0928-\u0938\u093e \u0939\u093e\u0925 \u091a\u0932\u093e\u0928\u093e \u0939\u0948; \u0924\u0940\u0930 \u0915\u094b \u0939\u0940 \u092c\u0924\u093e\u0928\u0947 \u0926\u0947\u0902, \u0914\u0930 \u0938\u0902\u0915\u0947\u0924 \u0915\u094b \u092c\u0938 '\u0905\u092d\u0940 \u0915\u0941\u091b \u0939\u094b\u0928\u0947 \u0935\u093e\u0932\u093e \u0939\u0948' \u0915\u0947 \u0907\u0936\u093e\u0930\u0947 \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u0932\u0947\u0902\u0964",duration:"\u090f\u0915 \u092a\u0942\u0930\u093e \u0926\u094c\u0930 \u0915\u0930\u0940\u092c 20 \u0938\u0947 30 \u092e\u093f\u0928\u091f \u0915\u093e \u0939\u094b\u0924\u093e \u0939\u0948, \u091c\u094b \u0915\u093f\u0938\u0940 \u0939\u0932\u094d\u0915\u0947-\u092b\u0941\u0932\u094d\u0915\u0947 \u0930\u094b\u091c\u093c\u093e\u0928\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0938\u0947 \u0915\u0939\u0940\u0902 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0939\u0948\u0964 \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u0915\u0941\u091b\u0947\u0915 \u092c\u093e\u0930 10 \u0938\u0947 15 \u092e\u093f\u0928\u091f \u0915\u0947 \u091b\u094b\u091f\u0947 \u0938\u0924\u094d\u0930 \u0907\u0938 \u0915\u093e\u0930\u094d\u092f \u092e\u0947\u0902 \u092a\u0948\u0928\u0947\u092a\u0928 \u0915\u094b \u092c\u0928\u093e\u090f \u0930\u0916\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0915\u093e\u092b\u093c\u0940 \u0939\u0948\u0902; \u0907\u0938 \u092c\u093e\u0924 \u0915\u093e \u0915\u094b\u0908 \u0938\u092c\u0942\u0924 \u0928\u0939\u0940\u0902 \u0915\u093f \u0918\u0902\u091f\u094b\u0902 \u0924\u0915 \u0907\u0938\u0947 \u0930\u091f\u0928\u0947 \u0938\u0947 \u0915\u0941\u091b \u0914\u0930 \u091c\u0941\u0921\u093c\u0924\u093e \u0939\u0948\u0964",research:"\u0938\u092c\u0942\u0924 \u0920\u0940\u0915 \u0909\u0938\u0940 \u092c\u093e\u0924 \u0915\u0947 \u0932\u093f\u090f \u0938\u092c\u0938\u0947 \u092e\u091c\u093c\u092c\u0942\u0924 \u0939\u0948\u0902 \u091c\u093f\u0938\u0915\u0940 \u0906\u092a \u0909\u092e\u094d\u092e\u0940\u0926 \u0915\u0930\u0947\u0902\u0917\u0947: \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0947 \u0938\u093e\u0925 \u0906\u092a \u0907\u0938 \u0916\u093e\u0938 \u0938\u0902\u0915\u0947\u0924-flanker \u0915\u093e\u0930\u094d\u092f \u092e\u0947\u0902 \u0924\u0947\u091c\u093c \u0914\u0930 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0938\u0941\u0938\u0902\u0917\u0924 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u091f\u0915\u0930\u093e\u0935 (\u0915\u093e\u0930\u094d\u092f\u0915\u093e\u0930\u0940) \u0935\u093e\u0932\u093e \u0938\u094d\u0915\u094b\u0930 \u0938\u0924\u094d\u0930-\u0926\u0930-\u0938\u0924\u094d\u0930 \u0920\u0940\u0915-\u0920\u093e\u0915 \u0938\u094d\u0925\u093f\u0930 \u0930\u0939\u0924\u093e \u0939\u0948\u0964 \u092a\u0947\u091a \u0938\u093e\u0907\u0915\u094b\u092e\u0947\u091f\u094d\u0930\u093f\u0915 \u0939\u0948: alerting \u0914\u0930 orienting \u0915\u0947 \u0905\u0902\u0924\u0930-\u0938\u094d\u0915\u094b\u0930 \u0905\u0938\u094d\u0925\u093f\u0930 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902 \u0914\u0930 \u092c\u0948\u0920\u0915\u094b\u0902 \u0915\u0947 \u092c\u0940\u091a \u0905\u091a\u094d\u091b\u0940 \u0924\u0930\u0939 \u0928\u0939\u0940\u0902 \u0926\u094b\u0939\u0930\u093e\u090f \u091c\u093e\u0924\u0947, \u0907\u0938\u0932\u093f\u090f \u0907\u0928\u0915\u0940 \u090f\u0915\u0932 \u0930\u0940\u0921\u093f\u0902\u0917 \u0915\u093e \u092c\u0939\u0941\u0924 \u0915\u092e \u092e\u0924\u0932\u092c \u0939\u0948\u0964 \u092f\u0947 \u0926\u093e\u0935\u0947 \u0915\u093f ANT \u0915\u093e \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u0927\u094d\u092f\u093e\u0928 \u0915\u094b \u091a\u094c\u0921\u093c\u093e \u0915\u0930\u0924\u093e \u0939\u0948, \u092c\u0941\u0926\u094d\u0927\u093f \u092c\u0922\u093c\u093e\u0924\u093e \u0939\u0948 \u092f\u093e \u0938\u0902\u091c\u094d\u091e\u093e\u0928\u093e\u0924\u094d\u092e\u0915 \u0917\u093f\u0930\u093e\u0935\u091f \u0915\u094b \u0930\u094b\u0915\u0924\u093e \u0939\u0948 \u2014 \u0938\u094d\u0925\u093e\u092a\u093f\u0924 \u0928\u0939\u0940\u0902 \u0939\u0948\u0902, \u0907\u0938\u0932\u093f\u090f \u092c\u0921\u093c\u0947-\u092c\u0921\u093c\u0947 \u0935\u093e\u0926\u094b\u0902 \u0915\u094b \u0938\u093e\u0935\u0927\u093e\u0928\u0940 \u0938\u0947 \u0932\u0947\u0902\u0964",rec:"\u0907\u0938\u0947 \u090f\u0915 \u0915\u0947\u0902\u0926\u094d\u0930\u093f\u0924 \u0935\u093e\u0930\u094d\u092e-\u0905\u092a \u0915\u0940 \u0924\u0930\u0939 \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0915\u0930\u0947\u0902: \u0928\u093f\u0917\u093e\u0939 \u091c\u092e\u093e\u090f \u0914\u0930 \u0938\u091f\u0940\u0915\u0924\u093e \u092a\u0930 \u0928\u091c\u093c\u0930 \u0930\u0916\u0924\u0947 \u0939\u0941\u090f \u090f\u0915 \u0938\u093e\u092b\u093c-\u0938\u0941\u0925\u0930\u093e \u0926\u094c\u0930, \u0928 \u0915\u093f \u0917\u0924\u093f \u0915\u0947 \u092a\u0940\u091b\u0947 \u092d\u093e\u0917\u0924\u0947 \u0915\u0908 \u0932\u093e\u092a\u0930\u0935\u093e\u0939 \u0926\u094c\u0930\u0964",faq:[["\u0909\u0928 \u0924\u0940\u0928\u094b\u0902 \u0938\u094d\u0915\u094b\u0930\u094b\u0902 \u0915\u093e \u0905\u0938\u0932 \u092e\u0947\u0902 \u0915\u094d\u092f\u093e \u092e\u0924\u0932\u092c \u0939\u0948?","\u0939\u0930 \u090f\u0915 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0917\u0924\u093f \u092e\u0947\u0902 \u0905\u0902\u0924\u0930 \u0939\u0948: alerting \u092f\u0939 \u0939\u0948 \u0915\u093f \u090f\u0915 \u091a\u0947\u0924\u093e\u0935\u0928\u0940 \u0938\u0902\u0915\u0947\u0924 \u0906\u092a\u0915\u094b \u0915\u093f\u0924\u0928\u093e \u0924\u0947\u091c\u093c \u0915\u0930 \u0926\u0947\u0924\u093e \u0939\u0948, orienting \u0909\u0938 \u0938\u0902\u0915\u0947\u0924 \u0915\u093e \u092b\u093c\u093e\u092f\u0926\u093e \u0939\u0948 \u091c\u094b \u0926\u093f\u0916\u093e \u0926\u0947\u0924\u093e \u0939\u0948 \u0915\u093f \u0932\u0915\u094d\u0937\u094d\u092f \u0915\u0939\u093e\u0901 \u0939\u094b\u0917\u093e, \u0914\u0930 executive control \u092f\u0939 \u0939\u0948 \u0915\u093f \u091f\u0915\u0930\u093e\u0935 \u0935\u093e\u0932\u0947 \u0915\u093f\u0928\u093e\u0930\u0947 \u0915\u0947 \u0924\u0940\u0930 \u0906\u092a\u0915\u094b \u0915\u093f\u0924\u0928\u093e \u0927\u0940\u092e\u093e \u0915\u0930 \u0926\u0947\u0924\u0947 \u0939\u0948\u0902\u0964"],["\u0915\u094d\u092f\u093e ANT \u092e\u0947\u0930\u0947 \u0927\u094d\u092f\u093e\u0928 \u0915\u093e \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u092e\u093e\u092a \u0939\u0948?","\u0906\u0902\u0936\u093f\u0915 \u0930\u0942\u092a \u0938\u0947\u0964 executive-control (\u091f\u0915\u0930\u093e\u0935) \u0935\u093e\u0932\u093e \u0938\u094d\u0915\u094b\u0930 \u0915\u093e\u092b\u093c\u0940 \u0938\u094d\u0925\u093f\u0930 \u0939\u0948, \u092a\u0930 alerting \u0914\u0930 orienting \u0935\u093e\u0932\u0947 \u0938\u094d\u0915\u094b\u0930 \u0938\u093e\u0902\u0916\u094d\u092f\u093f\u0915\u0940\u092f \u0930\u0942\u092a \u0938\u0947 \u0905\u0938\u094d\u0925\u093f\u0930 \u0939\u0948\u0902, \u0907\u0938\u0932\u093f\u090f \u0915\u093f\u0938\u0940 \u090f\u0915 \u0928\u0924\u0940\u091c\u0947 \u0915\u094b \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0928 \u092a\u0922\u093c\u0947\u0902, \u0916\u093e\u0938\u0915\u0930 \u0909\u0928 \u0926\u094b\u0928\u094b\u0902 \u0915\u0947 \u0932\u093f\u090f\u0964"],["\u0915\u094d\u092f\u093e ANT \u0915\u093e \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u092e\u0941\u091d\u0947 \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0940 \u091c\u093c\u093f\u0902\u0926\u0917\u0940 \u092e\u0947\u0902 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0927\u094d\u092f\u093e\u0928\u092e\u0917\u094d\u0928 \u092c\u0928\u093e \u0926\u0947\u0917\u093e?","\u0906\u092a ANT \u092e\u0947\u0902 \u0924\u094b \u0938\u093e\u092b\u093c \u0924\u094c\u0930 \u092a\u0930 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b\u0902\u0917\u0947, \u092a\u0930 \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0947 \u0927\u094d\u092f\u093e\u0928 \u0924\u0915 \u0935\u094d\u092f\u093e\u092a\u0915 \u092b\u0948\u0932\u093e\u0935 \u092a\u094d\u0930\u092e\u093e\u0923\u093f\u0924 \u0928\u0939\u0940\u0902 \u0939\u0948\u0964 \u0907\u0938\u0947 \u0932\u0915\u094d\u0937\u093f\u0924 \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0947 \u0924\u094c\u0930 \u092a\u0930 \u0932\u0947\u0902, \u0905\u092a\u0928\u0947 \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u0927\u094d\u092f\u093e\u0928 \u0915\u0947 \u092a\u0915\u094d\u0915\u0947 \u0938\u0941\u0927\u093e\u0930 \u0915\u0947 \u0924\u094c\u0930 \u092a\u0930 \u0928\u0939\u0940\u0902\u0964"]],variants:"\u0906\u092e \u0938\u0902\u0938\u094d\u0915\u0930\u0923\u094b\u0902 \u092e\u0947\u0902 \u0936\u093e\u092e\u093f\u0932 \u0939\u0948\u0902: \u092c\u091a\u094d\u091a\u094b\u0902 \u0935\u093e\u0932\u093e (\u092e\u091b\u0932\u0940) \u0938\u0902\u0938\u094d\u0915\u0930\u0923; ANT-R (\u0938\u0902\u0936\u094b\u0927\u093f\u0924) \u091c\u093f\u0938\u092e\u0947\u0902 \u0928\u0947\u091f\u0935\u0930\u094d\u0915-\u0905\u0902\u0924\u0903\u0915\u094d\u0930\u093f\u092f\u093e\u0913\u0902 \u0915\u094b \u092a\u0930\u0916\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0905\u0924\u093f\u0930\u093f\u0915\u094d\u0924 \u0938\u0902\u0915\u0947\u0924 \u0914\u0930 flanker \u0938\u092e\u092f-\u0905\u0902\u0924\u0930\u093e\u0932 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902; Attention Network Test for Interactions and Vigilance (ANTI-V) \u091c\u094b \u090f\u0915 \u0928\u093f\u0930\u0902\u0924\u0930-\u0927\u094d\u092f\u093e\u0928 \u0935\u093e\u0932\u093e \u0918\u091f\u0915 \u091c\u094b\u0921\u093c\u0924\u093e \u0939\u0948; \u0914\u0930 \u092a\u093e\u0930\u094d\u0936\u094d\u0935\u0915\u0943\u0924 (lateralised) \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u091c\u094b \u0932\u0915\u094d\u0937\u094d\u092f \u0915\u094b \u0915\u093f\u0938\u0940 \u090f\u0915 \u0926\u0943\u0936\u094d\u092f-\u0915\u094d\u0937\u0947\u0924\u094d\u0930 \u092e\u0947\u0902 \u0926\u093f\u0916\u093e\u0924\u0947 \u0939\u0948\u0902\u0964"},zh:{about:"ANT \u662f\u4e00\u9879\u5e26\u63d0\u793a\u7684\u7bad\u5934\u4efb\u52a1\u3002\u6bcf\u4e00\u8bd5\u6b21\u4e2d\uff0c\u4f60\u5148\u7b49\u4e00\u4e2a\u6ce8\u89c6\u5341\u5b57\uff0c\u6709\u65f6\u4f1a\u770b\u5230\u4e00\u4e2a\u63d0\u793a\uff08\u5728\u76ee\u6807\u5373\u5c06\u51fa\u73b0\u7684\u4f4d\u7f6e\u4e0a\u65b9\u6216\u4e0b\u65b9\u95ea\u4e00\u4e0b\uff09\uff0c\u968f\u540e\u662f\u4e00\u4e2a\u88ab\u5176\u4ed6\u7bad\u5934\u5939\u5728\u4e2d\u95f4\u7684\u4e2d\u592e\u7bad\u5934\uff0c\u4f60\u53ea\u9700\u6839\u636e\u4e2d\u592e\u7bad\u5934\u7684\u6307\u5411\u6309\u5de6\u6216\u6309\u53f3\uff0c\u800c\u65e0\u89c6\u5b83\u7684\u90bb\u5c45\u3002\u901a\u8fc7\u6bd4\u8f83\u4f60\u5728\u4e0d\u540c\u63d0\u793a\u7c7b\u578b\u548c\u4e0d\u540c\u5939\u6270\u7c7b\u578b\u4e0b\u7684\u53cd\u5e94\u65f6\uff0c\u8fd9\u9879\u6d4b\u9a8c\u80fd\u5206\u522b\u4f30\u51fa\u4e09\u6837\u4e1c\u897f\uff1a\u8b66\u89c9\u3001\u5b9a\u5411\u548c\u51b2\u7a81\u89e3\u51b3\u3002",benefit:"\u5b83\u953b\u70bc\u9009\u62e9\u6027\u6ce8\u610f\u548c\u6267\u884c\u6027\u6ce8\u610f\uff0c\u5c24\u5176\u662f\u9501\u5b9a\u4e00\u4e2a\u76ee\u6807\u3001\u538b\u5236\u5468\u56f4\u5e72\u6270\u4fe1\u606f\u7684\u80fd\u529b\uff0c\u5916\u52a0\u6ce8\u610f\u4e2d\u8d1f\u8d23\u9884\u5907\u72b6\u6001\u548c\u7a7a\u95f4\u5b9a\u5411\u7684\u90a3\u4e00\u9762\u3002",history:"\u5b83\u8131\u80ce\u4e8e\u6570\u5341\u5e74\u7684\u6ce8\u610f\u7814\u7a76\uff0c\u5e76\u4e8e 2002 \u5e74\u4f5c\u4e3a\u4e00\u9879\u5408\u4e8c\u4e3a\u4e00\u7684\u4efb\u52a1\u53d1\u8868\uff0c\u878d\u5408\u4e86\u4e24\u4e2a\u7ecf\u5178\u8303\u5f0f\uff1aPosner \u7684\u7a7a\u95f4\u63d0\u793a\u548c Eriksen \u7684\u5939\u6270\u4efb\u52a1\u3002\u7531\u4e8e\u5b83\u77ed\u5c0f\u3001\u4e0d\u4f9d\u8d56\u8bed\u8a00\uff0c\u800c\u4e14\u5bf9\u513f\u7ae5\u3001\u60a3\u8005\u4e43\u81f3\u7334\u5b50\u90fd\u9002\u7528\uff0c\u5b83\u5f88\u5feb\u4f20\u904d\u4e86\u8ba4\u77e5\u795e\u7ecf\u79d1\u5b66\u3001fMRI \u548c\u9057\u4f20\u5b66\u5b9e\u9a8c\u5ba4\uff0c\u5982\u4eca\u5df2\u6709\u8bb8\u591a\u4fee\u8ba2\u5f62\u5f0f\u3002",creator:"\u6ce8\u610f\u7f51\u7edc\u6d4b\u9a8c\uff08Attention Network Test\uff09\u7531 Jin Fan\u3001Bruce McCandliss\u3001Tobias Sommer\u3001Amir Raz \u548c Michael Posner \u521b\u5236\uff0c2002 \u5e74\u53d1\u8868\u4e8e\u300aJournal of Cognitive Neuroscience\u300b\u3002\u5b83\u628a Posner \u548c Petersen \u4e8e 1990 \u5e74\u63d0\u51fa\u7684\u6ce8\u610f\u4e09\u7f51\u7edc\u6a21\u578b\u53d8\u6210\u4e86\u53ef\u64cd\u4f5c\u7684\u6d4b\u91cf\u3002",methods:"\u628a\u76ee\u5149\u4fdd\u6301\u5728\u4e2d\u592e\u6ce8\u89c6\u70b9\u4e0a\uff0c\u53ea\u5bf9\u4e2d\u95f4\u90a3\u4e2a\u7bad\u5934\u53cd\u5e94\uff0c\u7edd\u4e0d\u8981\u5bf9\u4e24\u4fa7\u7684\u7bad\u5934\u53cd\u5e94\u3002\u5148\u6c42\u51c6\u3001\u518d\u8ba9\u5feb\u968f\u4e4b\u800c\u6765\uff0c\u56e0\u4e3a\u5728\u51b2\u7a81\u8bd5\u6b21\u4e0a\u62a2\u5feb\u4f1a\u63a8\u9ad8\u9519\u8bef\u7387\u3002\u522b\u9884\u5148\u731c\u54ea\u4e00\u8fb9\uff1b\u8ba9\u7bad\u5934\u6765\u544a\u8bc9\u4f60\uff0c\u800c\u628a\u63d0\u793a\u4ec5\u4ec5\u5f53\u4f5c\u300c\u6709\u4e8b\u8981\u53d1\u751f\u4e86\u300d\u7684\u4fe1\u53f7\u3002",duration:"\u5b8c\u6574\u8dd1\u4e00\u904d\u5927\u7ea6 20 \u5230 30 \u5206\u949f\uff0c\u8fd9\u6bd4\u968f\u624b\u505a\u7684\u6bcf\u65e5\u7ec3\u4e60\u8981\u957f\u3002\u6bcf\u5468\u51e0\u6b21\u3001\u6bcf\u6b21 10 \u5230 15 \u5206\u949f\u7684\u77ed\u65f6\u6bb5\uff0c\u5c31\u8db3\u4ee5\u8ba9\u4f60\u5728\u8fd9\u9879\u4efb\u52a1\u4e0a\u4fdd\u6301\u624b\u611f\uff1b\u6ca1\u6709\u8bc1\u636e\u8868\u660e\u8fde\u78e8\u51e0\u4e2a\u5c0f\u65f6\u4f1a\u591a\u5e26\u6765\u4ec0\u4e48\u3002",research:"\u8bc1\u636e\u6700\u624e\u5b9e\u7684\u6070\u6070\u662f\u4f60\u80fd\u60f3\u5230\u7684\u90a3\u90e8\u5206\uff1a\u968f\u7740\u7ec3\u4e60\uff0c\u4f60\u5728\u8fd9\u9879\u7279\u5b9a\u7684\u300c\u63d0\u793a+\u5939\u6270\u300d\u4efb\u52a1\u4e0a\u4f1a\u66f4\u5feb\u3001\u66f4\u7a33\u5b9a\uff0c\u800c\u51b2\u7a81\uff08\u6267\u884c\uff09\u5206\u6570\u5728\u4e0d\u540c\u6b21\u6d4b\u9a8c\u4e4b\u95f4\u4e5f\u76f8\u5f53\u7a33\u5b9a\u3002\u95ee\u9898\u51fa\u5728\u5fc3\u7406\u6d4b\u91cf\u5b66\u4e0a\uff1a\u8b66\u89c9\u5206\u6570\u548c\u5b9a\u5411\u5206\u6570\u90fd\u5f88\u300c\u5435\u300d\uff0c\u5728\u4e0d\u540c\u573a\u6b21\u4e4b\u95f4\u590d\u73b0\u5f97\u5f88\u5dee\uff0c\u6240\u4ee5\u5355\u6b21\u8bfb\u6570\u51e0\u4e4e\u8bf4\u660e\u4e0d\u4e86\u4ec0\u4e48\u3002\u81f3\u4e8e\u300c\u8bad\u7ec3 ANT \u80fd\u62d3\u5bbd\u6574\u4f53\u6ce8\u610f\u529b\u3001\u63d0\u5347\u667a\u529b\u6216\u5ef6\u7f13\u8ba4\u77e5\u8870\u9000\u300d\u7684\u8bf4\u6cd5\u90fd\u672a\u88ab\u786e\u7acb\uff0c\u6240\u4ee5\u5bf9\u90a3\u4e9b\u5b8f\u5927\u627f\u8bfa\u8981\u4fdd\u6301\u8c28\u614e\u3002",rec:"\u628a\u5b83\u5f53\u4f5c\u4e00\u6b21\u6709\u9488\u5bf9\u6027\u7684\u70ed\u8eab\uff1a\u76ee\u5149\u56fa\u5b9a\u3001\u53ea\u76ef\u51c6\u786e\u7387\uff0c\u8ba4\u771f\u8dd1\u4e00\u904d\u5e72\u51c0\u7684\uff0c\u80dc\u8fc7\u9a6c\u864e\u62a2\u5feb\u5730\u8dd1\u5f88\u591a\u904d\u3002",faq:[["\u8fd9\u4e09\u4e2a\u5206\u6570\u5230\u5e95\u610f\u5473\u7740\u4ec0\u4e48\uff1f","\u6bcf\u4e00\u4e2a\u90fd\u662f\u53cd\u5e94\u65f6\u4e4b\u5dee\uff1a\u8b66\u89c9\u662f\u4e00\u4e2a\u9884\u8b66\u63d0\u793a\u8ba9\u4f60\u63d0\u901f\u4e86\u591a\u5c11\uff0c\u5b9a\u5411\u662f\u4e00\u4e2a\u80fd\u6307\u51fa\u76ee\u6807\u4f4d\u7f6e\u7684\u63d0\u793a\u5e26\u6765\u7684\u597d\u5904\uff0c\u6267\u884c\u63a7\u5236\u662f\u76f8\u51b2\u7a81\u7684\u5939\u6270\u7bad\u5934\u8ba9\u4f60\u6162\u4e86\u591a\u5c11\u3002"],["ANT \u662f\u8861\u91cf\u6211\u6ce8\u610f\u529b\u7684\u53ef\u9760\u6307\u6807\u5417\uff1f","\u90e8\u5206\u662f\u3002\u6267\u884c\u63a7\u5236\uff08\u51b2\u7a81\uff09\u5206\u6570\u76f8\u5f53\u7a33\u5b9a\uff0c\u4f46\u8b66\u89c9\u548c\u5b9a\u5411\u5206\u6570\u5728\u7edf\u8ba1\u4e0a\u5f88\u5435\uff0c\u6240\u4ee5\u522b\u5bf9\u5355\u6b21\u7ed3\u679c\u8fc7\u5ea6\u89e3\u8bfb\uff0c\u5bf9\u8fd9\u4e24\u9879\u5c24\u5176\u5982\u6b64\u3002"],["\u5728 ANT \u4e0a\u8bad\u7ec3\u4f1a\u8ba9\u6211\u65e5\u5e38\u751f\u6d3b\u4e2d\u66f4\u4e13\u6ce8\u5417\uff1f","\u4f60\u663e\u7136\u4f1a\u5728 ANT \u672c\u8eab\u4e0a\u8fdb\u6b65\uff0c\u4f46\u80fd\u5426\u5e7f\u6cdb\u8fc1\u79fb\u5230\u65e5\u5e38\u4e13\u6ce8\u5c1a\u672a\u88ab\u8bc1\u5b9e\u3002\u628a\u5b83\u5f53\u4f5c\u6709\u9488\u5bf9\u6027\u7684\u7ec3\u4e60\uff0c\u800c\u4e0d\u662f\u5bf9\u4e00\u822c\u6ce8\u610f\u529b\u7684\u4fdd\u8bc1\u5347\u7ea7\u3002"]],variants:"\u5e38\u89c1\u53d8\u4f53\u5305\u62ec\uff1a\u513f\u7ae5\uff08\u5c0f\u9c7c\uff09\u7248\uff1bANT-R\uff08\u4fee\u8ba2\u7248\uff09\uff0c\u589e\u52a0\u4e86\u989d\u5916\u7684\u63d0\u793a\u548c\u5939\u6270\u65f6\u5e8f\u4ee5\u63a2\u67e5\u7f51\u7edc\u4e4b\u95f4\u7684\u76f8\u4e92\u4f5c\u7528\uff1b\u4ea4\u4e92\u4e0e\u8b66\u6212\u6ce8\u610f\u7f51\u7edc\u6d4b\u9a8c\uff08ANTI-V\uff09\uff0c\u52a0\u5165\u4e86\u4e00\u4e2a\u6301\u7eed\u6027\u6ce8\u610f\u6210\u5206\uff1b\u4ee5\u53ca\u628a\u76ee\u6807\u53ea\u5448\u73b0\u5728\u67d0\u4e00\u4fa7\u89c6\u91ce\u7684\u504f\u4fa7\u5316\u7248\u672c\u3002"}},"attention-conflict":{ru:{about:"\u0412 \xab\u041a\u043e\u043d\u0444\u043b\u0438\u043a\u0442\u0435 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f\xbb \u043f\u043e\u044f\u0432\u043b\u044f\u0435\u0442\u0441\u044f \u0441\u0442\u0438\u043c\u0443\u043b, \u0433\u0434\u0435 \u0434\u0432\u0435 \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u043a\u0438 \u043f\u0440\u043e\u0442\u0438\u0432\u043e\u0440\u0435\u0447\u0430\u0442 \u0434\u0440\u0443\u0433 \u0434\u0440\u0443\u0433\u0443, \u0438 \u043d\u0443\u0436\u043d\u043e \u0440\u0435\u0430\u0433\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u043d\u0430 \u0442\u0443, \u0447\u0442\u043e \u0432\u0430\u0436\u043d\u0430, \u0438\u0433\u043d\u043e\u0440\u0438\u0440\u0443\u044f \u043e\u0442\u0432\u043b\u0435\u043a\u0430\u044e\u0449\u0443\u044e. \u041a\u043b\u0430\u0441\u0441\u0438\u0447\u0435\u0441\u043a\u0438\u0439 \u043f\u0440\u0438\u043c\u0435\u0440: \u043d\u0430\u0437\u0432\u0430\u043d\u0438\u0435 \u0446\u0432\u0435\u0442\u0430 \u043d\u0430\u043f\u0435\u0447\u0430\u0442\u0430\u043d\u043e \u043d\u0435\u0441\u043e\u0432\u043f\u0430\u0434\u0430\u044e\u0449\u0438\u043c\u0438 \u0447\u0435\u0440\u043d\u0438\u043b\u0430\u043c\u0438, \u043d\u0430\u043f\u0440\u0438\u043c\u0435\u0440 \u0441\u043b\u043e\u0432\u043e \xab\u041a\u0420\u0410\u0421\u041d\u042b\u0419\xbb \u043d\u0430\u043f\u0438\u0441\u0430\u043d\u043e \u0441\u0438\u043d\u0438\u043c, \u0438 \u0432\u044b \u0434\u043e\u043b\u0436\u043d\u044b \u043d\u0430\u0437\u0432\u0430\u0442\u044c \u0446\u0432\u0435\u0442 \u0447\u0435\u0440\u043d\u0438\u043b, \u0430 \u043d\u0435 \u043f\u0440\u043e\u0447\u0438\u0442\u0430\u0442\u044c \u0441\u043b\u043e\u0432\u043e, \u0432\u044b\u0431\u0438\u0440\u0430\u044f \u0432\u0435\u0440\u043d\u044b\u0439 \u043e\u0442\u0432\u0435\u0442 \u043a\u0430\u043a \u043c\u043e\u0436\u043d\u043e \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u0438 \u0431\u0435\u0437 \u043e\u0448\u0438\u0431\u043e\u043a.",benefit:"\u0422\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u0438\u0437\u0431\u0438\u0440\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0435 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u0438 \u0442\u043e\u0440\u043c\u043e\u0436\u0435\u043d\u0438\u0435 \u0440\u0435\u0430\u043a\u0446\u0438\u0438 \u2014 \u0443\u043c\u0435\u043d\u0438\u0435 \u0437\u0430\u0446\u0435\u043f\u0438\u0442\u044c\u0441\u044f \u0437\u0430 \u043d\u0443\u0436\u043d\u044b\u0439 \u043f\u0440\u0438\u0437\u043d\u0430\u043a \u0438 \u043f\u043e\u0434\u0430\u0432\u0438\u0442\u044c \u0431\u043e\u043b\u0435\u0435 \u0441\u0438\u043b\u044c\u043d\u044b\u0439, \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u0438\u0439 \u043f\u043e\u0440\u044b\u0432. \u041f\u043e \u0441\u0443\u0442\u0438 \u0432\u044b \u043e\u0442\u0440\u0430\u0431\u0430\u0442\u044b\u0432\u0430\u0435\u0442\u0435 \u0442\u043e\u0442 \u0441\u0430\u043c\u044b\u0439 \u043c\u043e\u043c\u0435\u043d\u0442, \u043a\u043e\u0433\u0434\u0430 \u043b\u043e\u0432\u0438\u0442\u0435 \u0441\u0435\u0431\u044f \u0437\u0430 \u0440\u0443\u043a\u0443 \u0434\u043e \u0442\u043e\u0433\u043e, \u043a\u0430\u043a \u0432\u044b\u0441\u043a\u043e\u0447\u0438\u0442 \u043f\u0440\u0438\u0432\u044b\u0447\u043d\u044b\u0439 \u043d\u0435\u043f\u0440\u0430\u0432\u0438\u043b\u044c\u043d\u044b\u0439 \u043e\u0442\u0432\u0435\u0442.",history:"\u0416\u0430\u043d\u0440 \u0432\u044b\u0440\u043e\u0441 \u0438\u0437 \u0434\u0432\u0443\u0445 \u0437\u043d\u0430\u043a\u043e\u0432\u044b\u0445 \u044d\u043a\u0441\u043f\u0435\u0440\u0438\u043c\u0435\u043d\u0442\u043e\u0432 \u0432 \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u0438. \u0426\u0432\u0435\u0442\u043e\u0441\u043b\u043e\u0432\u043e\u0432\u043e\u0439 \u0432\u0430\u0440\u0438\u0430\u043d\u0442 \u0438\u0434\u0451\u0442 \u043e\u0442 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u0439 \u0438\u043d\u0442\u0435\u0440\u0444\u0435\u0440\u0435\u043d\u0446\u0438\u0438 \u0414\u0436\u043e\u043d\u0430 \u0420\u0438\u0434\u043b\u0438 \u0421\u0442\u0440\u0443\u043f\u0430 1935 \u0433\u043e\u0434\u0430, \u0430 \u0432\u0435\u0440\u0441\u0438\u0438 \u0441\u043e \u0441\u0442\u0440\u0435\u043b\u043a\u0430\u043c\u0438 \u0438 \u0431\u0443\u043a\u0432\u0430\u043c\u0438 \u2014 \u043e\u0442 \u0444\u043b\u0430\u043d\u0433\u043e\u0432\u043e\u0439 \u0437\u0430\u0434\u0430\u0447\u0438, \u043e\u043f\u0443\u0431\u043b\u0438\u043a\u043e\u0432\u0430\u043d\u043d\u043e\u0439 \u0411\u0430\u0440\u0431\u0430\u0440\u043e\u0439 \u0438 \u0427\u0430\u0440\u043b\u044c\u0437\u043e\u043c \u042d\u0440\u0438\u043a\u0441\u0435\u043d\u0430\u043c\u0438 \u0432 1974 \u0433\u043e\u0434\u0443. \u041e\u0431\u0435 \u0441\u0442\u0430\u043b\u0438 \u043e\u043f\u043e\u0440\u043e\u0439 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u0439 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f, \u0430 \u043f\u043e\u0437\u0436\u0435 \u043f\u0440\u0435\u0432\u0440\u0430\u0442\u0438\u043b\u0438\u0441\u044c \u0432 \u0431\u0435\u0441\u0447\u0438\u0441\u043b\u0435\u043d\u043d\u044b\u0435 \u044d\u043a\u0440\u0430\u043d\u043d\u044b\u0435 \u0442\u0440\u0435\u043d\u0430\u0436\u0451\u0440\u044b.",creator:"\u0423 \u044d\u0442\u043e\u0439 \u043a\u043e\u043d\u043a\u0440\u0435\u0442\u043d\u043e\u0439 \u0438\u0433\u0440\u044b \u043d\u0435\u0442 \u0435\u0434\u0438\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0433\u043e \u0430\u0432\u0442\u043e\u0440\u0430. \u041e\u043d\u0430 \u043f\u0440\u0438\u043d\u0430\u0434\u043b\u0435\u0436\u0438\u0442 \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u0438 \u043a\u043e\u043d\u0444\u043b\u0438\u043a\u0442\u043d\u044b\u0445 \u0437\u0430\u0434\u0430\u0447 \u0432 \u043a\u043e\u0433\u043d\u0438\u0442\u0438\u0432\u043d\u043e\u0439 \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u0438, \u0430 \u0434\u0432\u0430 \u0441\u0430\u043c\u044b\u0445 \u0438\u0437\u0432\u0435\u0441\u0442\u043d\u044b\u0445 \u0435\u0451 \u0440\u043e\u0434\u0438\u0442\u0435\u043b\u044f \u2014 \u0414\u0436. \u0420. \u0421\u0442\u0440\u0443\u043f, \u043e\u043f\u0438\u0441\u0430\u0432\u0448\u0438\u0439 \u044d\u0444\u0444\u0435\u043a\u0442 \u0446\u0432\u0435\u0442\u043e\u0441\u043b\u043e\u0432\u043e\u0432\u043e\u0439 \u0438\u043d\u0442\u0435\u0440\u0444\u0435\u0440\u0435\u043d\u0446\u0438\u0438 \u0432 1935 \u0433\u043e\u0434\u0443, \u0438 \u0411. \u0410. \u0438 \u0427. \u0423. \u042d\u0440\u0438\u043a\u0441\u0435\u043d\u044b, \u043f\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u0438\u0432\u0448\u0438\u0435 \u0444\u043b\u0430\u043d\u0433\u043e\u0432\u0443\u044e \u0437\u0430\u0434\u0430\u0447\u0443 \u0432 1974 \u0433\u043e\u0434\u0443.",methods:"\u0421\u0431\u0430\u0432\u044c\u0442\u0435 \u0442\u0435\u043c\u043f \u0440\u043e\u0432\u043d\u043e \u043d\u0430\u0441\u0442\u043e\u043b\u044c\u043a\u043e, \u0447\u0442\u043e\u0431\u044b \u043e\u0448\u0438\u0431\u043e\u043a \u0431\u044b\u043b\u043e \u043c\u0430\u043b\u043e: \u0433\u043e\u043d\u043a\u0430 \u0441 \u043f\u0440\u043e\u043c\u0430\u0445\u0430\u043c\u0438 \u0437\u0430\u043a\u0440\u0435\u043f\u043b\u044f\u0435\u0442 \u043d\u0435\u0432\u0435\u0440\u043d\u0443\u044e \u043f\u0440\u0438\u0432\u044b\u0447\u043a\u0443. \u041f\u043e\u043d\u0430\u0447\u0430\u043b\u0443 \u043f\u0440\u043e\u0433\u043e\u0432\u0430\u0440\u0438\u0432\u0430\u0439\u0442\u0435 \u043f\u0440\u0430\u0432\u0438\u043b\u043e \u0432\u0441\u043b\u0443\u0445 (\xab\u0446\u0432\u0435\u0442, \u0430 \u043d\u0435 \u0441\u043b\u043e\u0432\u043e\xbb), \u0434\u0435\u0440\u0436\u0438\u0442\u0435 \u0432\u0437\u0433\u043b\u044f\u0434 \u043d\u0430 \u043d\u0443\u0436\u043d\u043e\u043c \u043f\u0440\u0438\u0437\u043d\u0430\u043a\u0435 \u0438 \u043d\u0435 \u0434\u0430\u0432\u0430\u0439\u0442\u0435 \u0435\u043c\u0443 \u0441\u043f\u043e\u043b\u0437\u0430\u0442\u044c \u043d\u0430 \u043e\u0442\u0432\u043b\u0435\u043a\u0430\u044e\u0449\u0438\u0439, \u0430 \u043a\u043e\u0433\u0434\u0430 \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u044c \u0441\u0442\u0430\u043d\u0435\u0442 \u0441\u0442\u0430\u0431\u0438\u043b\u044c\u043d\u043e\u0439 \u2014 \u0434\u043e\u0431\u0430\u0432\u043b\u044f\u0439\u0442\u0435 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u0438 \u043d\u0430 \u0441\u043e\u0432\u043f\u0430\u0434\u0430\u044e\u0449\u0438\u0445, \u0438 \u043d\u0430 \u043a\u043e\u043d\u0444\u043b\u0438\u043a\u0442\u043d\u044b\u0445 \u043f\u0440\u043e\u0431\u0430\u0445.",duration:"\u041a\u043e\u0440\u043e\u0442\u043a\u043e \u0438 \u0447\u0430\u0441\u0442\u043e \u043b\u0443\u0447\u0448\u0435, \u0447\u0435\u043c \u0434\u043e\u043b\u0433\u043e \u0438 \u0440\u0435\u0434\u043a\u043e. \u041f\u044f\u0442\u0438-\u0434\u0435\u0441\u044f\u0442\u0438 \u043c\u0438\u043d\u0443\u0442 \u0432 \u0434\u0435\u043d\u044c \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0440\u0430\u0437 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e \u0434\u043e\u0441\u0442\u0430\u0442\u043e\u0447\u043d\u043e, \u0447\u0442\u043e\u0431\u044b \u043d\u0430\u0431\u0440\u0430\u0442\u044c \u0438 \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0442\u044c \u0440\u043e\u0432\u043d\u0443\u044e \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c; \u043e\u0431\u044b\u0447\u043d\u043e \u0432\u0440\u0435\u043c\u044f \u0440\u0435\u0430\u043a\u0446\u0438\u0438 \u0432\u044b\u0445\u043e\u0434\u0438\u0442 \u043d\u0430 \u043f\u043b\u0430\u0442\u043e \u0443\u0436\u0435 \u0432 \u043f\u0435\u0440\u0432\u0443\u044e-\u0432\u0442\u043e\u0440\u0443\u044e \u043d\u0435\u0434\u0435\u043b\u044e.",research:"\u0414\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u043d\u0435\u0435 \u0432\u0441\u0435\u0433\u043e \u0438\u043c\u0435\u043d\u043d\u043e \u0442\u043e, \u0447\u0435\u0433\u043e \u0438 \u0436\u0434\u0451\u0448\u044c, \u2014 \u0432\u044b \u0437\u0430\u043c\u0435\u0442\u043d\u043e \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u0438 \u0442\u043e\u0447\u043d\u0435\u0435 \u0441\u043f\u0440\u0430\u0432\u043b\u044f\u0435\u0442\u0435\u0441\u044c \u0441 \u0441\u0430\u043c\u0438\u043c\u0438 \u043a\u043e\u043d\u0444\u043b\u0438\u043a\u0442\u043d\u044b\u043c\u0438 \u0437\u0430\u0434\u0430\u0447\u0430\u043c\u0438, \u0430 \u0446\u0435\u043d\u0430 \u0438\u043d\u0442\u0435\u0440\u0444\u0435\u0440\u0435\u043d\u0446\u0438\u0438 \u0441 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u043e\u0439 \u043f\u0430\u0434\u0430\u0435\u0442. \u0423\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043d\u0438\u044f, \u0447\u0442\u043e \u044d\u0442\u043e \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0438\u0442\u0441\u044f \u043d\u0430 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u0432\u043e\u043e\u0431\u0449\u0435, \u0441\u0430\u043c\u043e\u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044c \u0432 \u0436\u0438\u0437\u043d\u0438 \u0438\u043b\u0438 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442, \u043a\u0443\u0434\u0430 \u0441\u043b\u0430\u0431\u0435\u0435: \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u0438\u0440\u0443\u0435\u043c\u044b\u0435 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u044f, \u0432\u043a\u043b\u044e\u0447\u0430\u044f \u043e\u043f\u044b\u0442 2024 \u0433\u043e\u0434\u0430 \u043d\u0430 \u0434\u0435\u0442\u044f\u0445, \u0440\u0430\u0437 \u0437\u0430 \u0440\u0430\u0437\u043e\u043c \u043d\u0430\u0445\u043e\u0434\u044f\u0442 \u0441\u043b\u0430\u0431\u044b\u0439 \u0431\u043b\u0438\u0436\u043d\u0438\u0439 \u0438 \u0434\u0430\u043b\u044c\u043d\u0438\u0439 \u043f\u0435\u0440\u0435\u043d\u043e\u0441, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u043a \u0433\u0440\u043e\u043c\u043a\u0438\u043c \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f\u043c \u0441\u0442\u043e\u0438\u0442 \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u044c\u0441\u044f \u0441\u0434\u0435\u0440\u0436\u0430\u043d\u043d\u043e.",rec:"\u0421\u043d\u0430\u0447\u0430\u043b\u0430 \u0434\u043e\u0431\u0438\u0432\u0430\u0439\u0442\u0435\u0441\u044c \u043d\u0438\u0437\u043a\u043e\u0433\u043e \u0438 \u0440\u043e\u0432\u043d\u043e\u0433\u043e \u043f\u0440\u043e\u0446\u0435\u043d\u0442\u0430 \u043e\u0448\u0438\u0431\u043e\u043a, \u0430 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u043f\u043e\u0434\u0442\u044f\u043d\u0435\u0442\u0441\u044f \u0441\u043b\u0435\u0434\u043e\u043c \u2014 \u0431\u044b\u0441\u0442\u0440\u044b\u0439 \u0437\u0430\u0431\u0435\u0433 \u0441 \u043f\u0440\u043e\u043c\u0430\u0445\u0430\u043c\u0438 \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u0440\u043e\u0432\u043d\u043e \u0442\u043e\u0442 \u0440\u0435\u0444\u043b\u0435\u043a\u0441, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u0432\u044b \u043f\u044b\u0442\u0430\u0435\u0442\u0435\u0441\u044c \u043f\u043e\u0434\u0430\u0432\u0438\u0442\u044c.",faq:[["\u041f\u043e\u0447\u0435\u043c\u0443 \u044f \u0432\u0441\u0451 \u0432\u0440\u0435\u043c\u044f \u0432\u044b\u043f\u0430\u043b\u0438\u0432\u0430\u044e \u043d\u0435\u043f\u0440\u0430\u0432\u0438\u043b\u044c\u043d\u044b\u0439 \u043e\u0442\u0432\u0435\u0442, \u0445\u043e\u0442\u044f \u0437\u043d\u0430\u044e \u043f\u0440\u0430\u0432\u0438\u043b\u043e?","\u041f\u043e\u0442\u043e\u043c\u0443 \u0447\u0442\u043e \u043f\u0440\u043e\u0447\u0438\u0442\u0430\u0442\u044c \u0441\u043b\u043e\u0432\u043e \u0438\u043b\u0438 \u043f\u043e\u0439\u0442\u0438 \u0437\u0430 \u0441\u0442\u0430\u0439\u043a\u043e\u0439 \u0441\u0442\u0440\u0435\u043b\u043e\u043a \u2014 \u0431\u044b\u0441\u0442\u0440\u043e \u0438 \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u0438, \u0430 \u043f\u0440\u0438\u043c\u0435\u043d\u0438\u0442\u044c \u043f\u0440\u0430\u0432\u0438\u043b\u043e \u2014 \u043c\u0435\u0434\u043b\u0435\u043d\u043d\u0435\u0435 \u0438 \u043e\u0441\u043e\u0437\u043d\u0430\u043d\u043d\u043e. \u042d\u0442\u043e\u0442 \u0440\u0430\u0437\u0440\u044b\u0432 \u0438 \u0435\u0441\u0442\u044c \u0441\u0443\u0442\u044c \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u044f, \u0430 \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0430 \u043a\u0430\u043a \u0440\u0430\u0437 \u0435\u0433\u043e \u0441\u0443\u0436\u0430\u0435\u0442."],["\u0421\u0442\u0430\u043d\u0443 \u043b\u0438 \u044f \u0432\u043d\u0438\u043c\u0430\u0442\u0435\u043b\u044c\u043d\u0435\u0435 \u0432 \u043e\u0431\u044b\u0447\u043d\u043e\u0439 \u0436\u0438\u0437\u043d\u0438?","\u0427\u0435\u0441\u0442\u043d\u043e \u2014 \u0432\u0440\u044f\u0434 \u043b\u0438 \u0441\u0438\u043b\u044c\u043d\u043e. \u0412 \u0441\u0430\u043c\u0438\u0445 \u043a\u043e\u043d\u0444\u043b\u0438\u043a\u0442\u043d\u044b\u0445 \u0437\u0430\u0434\u0430\u0447\u0430\u0445 \u0432\u044b \u0437\u0430\u043c\u0435\u0442\u043d\u043e \u043f\u0440\u0438\u0431\u0430\u0432\u0438\u0442\u0435, \u043d\u043e \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u044f \u043f\u043e\u043a\u0430\u0437\u044b\u0432\u0430\u044e\u0442, \u0447\u0442\u043e \u0448\u0438\u0440\u043e\u043a\u0438\u0439 \u043f\u0435\u0440\u0435\u043d\u043e\u0441 \u043d\u0430 \u0440\u0435\u0430\u043b\u044c\u043d\u0443\u044e \u043a\u043e\u043d\u0446\u0435\u043d\u0442\u0440\u0430\u0446\u0438\u044e \u0441\u043b\u0430\u0431\u044b\u0439 \u0438 \u043d\u0435\u043d\u0430\u0434\u0451\u0436\u043d\u044b\u0439, \u0442\u0430\u043a \u0447\u0442\u043e \u0432\u043e\u0441\u043f\u0440\u0438\u043d\u0438\u043c\u0430\u0439\u0442\u0435 \u044d\u0442\u043e \u043a\u0430\u043a \u0442\u043e\u0447\u0435\u0447\u043d\u0443\u044e \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0443, \u0430 \u043d\u0435 \u043b\u0435\u043a\u0430\u0440\u0441\u0442\u0432\u043e \u043e\u0442 \u0440\u0430\u0441\u0441\u0435\u044f\u043d\u043d\u043e\u0441\u0442\u0438."],["\u041d\u0430 \u0447\u0442\u043e \u0446\u0435\u043b\u0438\u0442\u044c\u0441\u044f \u2014 \u043d\u0430 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u0438\u043b\u0438 \u043d\u0430 \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u044c?","\u0421\u043d\u0430\u0447\u0430\u043b\u0430 \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u044c. \u041a\u043e\u0433\u0434\u0430 \u043e\u0448\u0438\u0431\u043a\u0438 \u0441\u0442\u0430\u043d\u0443\u0442 \u0440\u0435\u0434\u043a\u0438\u043c\u0438, \u0430\u043a\u043a\u0443\u0440\u0430\u0442\u043d\u043e \u043f\u0440\u0438\u0431\u0430\u0432\u043b\u044f\u0439\u0442\u0435 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c; \u043f\u043e\u0433\u043e\u043d\u044f \u0437\u0430 \u0447\u0438\u0441\u0442\u043e\u0439 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c\u044e \u0440\u0430\u043d\u044c\u0448\u0435 \u044d\u0442\u043e\u0433\u043e \u043f\u0440\u043e\u0441\u0442\u043e \u043f\u0440\u0438\u0443\u0447\u0430\u0435\u0442 \u0432\u044b\u0441\u0442\u0440\u0435\u043b\u0438\u0432\u0430\u0442\u044c \u043d\u0435\u043f\u0440\u0430\u0432\u0438\u043b\u044c\u043d\u044b\u0439 \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u0438\u0439 \u043e\u0442\u0432\u0435\u0442."]],variants:"\u0426\u0432\u0435\u0442\u043e\u0441\u043b\u043e\u0432\u043e\u0432\u043e\u0439 \u0421\u0442\u0440\u0443\u043f, \u0444\u043b\u0430\u043d\u0433\u043e\u0432\u0430\u044f \u0437\u0430\u0434\u0430\u0447\u0430 \u0441\u043e \u0441\u0442\u0440\u0435\u043b\u043a\u0430\u043c\u0438 \u0438\u043b\u0438 \u0431\u0443\u043a\u0432\u0430\u043c\u0438 \u043f\u043e \u0431\u043e\u043a\u0430\u043c, \u0447\u0438\u0441\u043b\u043e\u0432\u044b\u0435 \u0432\u0435\u0440\u0441\u0438\u0438, \u0433\u0434\u0435 \u0440\u0430\u0437\u043c\u0435\u0440 \u0441\u043f\u043e\u0440\u0438\u0442 \u0441\u043e \u0437\u043d\u0430\u0447\u0435\u043d\u0438\u0435\u043c. \u0412 \u0441\u043b\u043e\u0436\u043d\u044b\u0445 \u0440\u0435\u0436\u0438\u043c\u0430\u0445 \u043f\u0440\u0430\u0432\u0438\u043b\u043e \u043c\u0435\u043d\u044f\u0435\u0442\u0441\u044f \u043f\u043e \u0445\u043e\u0434\u0443 \u0438\u0433\u0440\u044b, \u0434\u043e\u0431\u0430\u0432\u043b\u044f\u0435\u0442\u0441\u044f \u043b\u0438\u043c\u0438\u0442 \u0432\u0440\u0435\u043c\u0435\u043d\u0438 \u0438\u043b\u0438 \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0430\u0435\u0442\u0441\u044f \u0446\u0435\u043b\u0435\u0432\u043e\u0439 \u043f\u0440\u0438\u0437\u043d\u0430\u043a, \u0447\u0442\u043e\u0431\u044b \u043d\u0435\u043b\u044c\u0437\u044f \u0431\u044b\u043b\u043e \u0438\u0433\u0440\u0430\u0442\u044c \u043d\u0430 \u0430\u0432\u0442\u043e\u043f\u0438\u043b\u043e\u0442\u0435."},en:{about:"Attention Conflict shows you a stimulus where two cues disagree, and your job is to respond to the one that matters while ignoring the one that distracts. A classic example is a colour word printed in a mismatched ink, like the word RED written in blue, where you must name the ink and not read the word, tapping the correct answer as quickly and accurately as you can.",benefit:"It trains selective attention and response inhibition, the ability to lock onto the relevant feature and override a stronger, more automatic impulse. You are practising the moment of catching yourself before the wrong, habitual answer slips out.",history:"The genre grew out of two landmark experiments in experimental psychology. The colour-word version comes from John Ridley Stroop's 1935 interference studies, and the arrow and letter versions descend from the flanker task published by Barbara and Charles Eriksen in 1974. Both became staples of attention research and were later adapted into countless screen-based training games.",creator:"There is no single inventor of this exact game. It belongs to the conflict-task tradition in cognitive psychology, with the two best-known parents being J. R. Stroop, who published the colour-word interference effect in 1935, and B. A. and C. W. Eriksen, who introduced the flanker task in 1974.",methods:"Slow down just enough to keep errors low, because rushing into mistakes teaches the wrong habit. Name the rule out loud at first (\"ink, not word\"), keep your eyes on the target feature rather than letting them drift to the distractor, and once accuracy is solid, push for speed on the congruent and incongruent trials alike.",duration:"Short and frequent beats long and rare. Five to ten minutes a day, a few days a week, is plenty to build and hold a stable speed, and you will usually see your reaction time settle within the first week or two.",research:"Evidence is strongest for exactly what you would expect \u2014 you get measurably faster and more accurate at conflict tasks themselves, and the interference cost shrinks with practice. Claims that this carries over to general attention, self-control in daily life or intelligence are much weaker; controlled studies, including a 2024 trial in children, repeatedly find little near or far transfer, so treat the grand promises with caution.",rec:"Chase a low, steady error rate first and let speed follow \u2014 a fast run full of mistakes trains exactly the reflex you are trying to suppress.",faq:[["Why do I keep blurting out the wrong answer even when I know the rule?","Because reading a word or following a crowd of arrows is automatic and fast, while applying the rule is deliberate and slower. That gap is the whole point of the exercise, and the practice is what narrows it."],["Will this make me more focused in everyday life?","Honestly, probably not in a big way. You will clearly get better at conflict tasks like this one, but the research shows that broad carry-over to real-world focus is weak and unreliable, so enjoy it as targeted practice rather than a cure for distraction."],["Should I aim for speed or accuracy?","Accuracy first. Once you are rarely making mistakes, gently push your speed; chasing raw speed before that just trains you to fire off the wrong, automatic response."]],variants:"The colour-word Stroop, the arrow or letter flanker with distractors on either side, and number versions where size conflicts with value. Harder modes flip the rule mid-game, add a time limit, or switch which feature is the target so you cannot run on autopilot."},es:{about:"Conflicto de Atenci\xf3n te muestra un est\xedmulo en el que dos se\xf1ales no coinciden, y tu tarea es responder a la que importa mientras ignoras la que distrae. Un ejemplo cl\xe1sico es una palabra de color impresa en una tinta que no concuerda, como la palabra ROJO escrita en azul, donde debes nombrar la tinta y no leer la palabra, tocando la respuesta correcta con la mayor rapidez y precisi\xf3n posible.",benefit:"Entrena la atenci\xf3n selectiva y la inhibici\xf3n de respuestas, la capacidad de fijarte en el rasgo relevante y anular un impulso m\xe1s fuerte y autom\xe1tico. Est\xe1s practicando ese instante de pillarte a ti mismo antes de que se te escape la respuesta equivocada y habitual.",history:"El g\xe9nero surgi\xf3 de dos experimentos emblem\xe1ticos de la psicolog\xeda experimental. La versi\xf3n de palabra-color proviene de los estudios de interferencia de John Ridley Stroop de 1935, y las versiones de flechas y letras descienden de la tarea de flancos publicada por Barbara y Charles Eriksen en 1974. Ambas se volvieron pilares de la investigaci\xf3n sobre la atenci\xf3n y m\xe1s tarde se adaptaron a innumerables juegos de entrenamiento en pantalla.",creator:"No hay un \xfanico inventor de este juego en concreto. Pertenece a la tradici\xf3n de las tareas de conflicto de la psicolog\xeda cognitiva, con sus dos padres m\xe1s conocidos: J. R. Stroop, que public\xf3 el efecto de interferencia palabra-color en 1935, y B. A. y C. W. Eriksen, que introdujeron la tarea de flancos en 1974.",methods:"Baja el ritmo lo justo para mantener pocos errores, porque lanzarte a equivocarte ense\xf1a el h\xe1bito equivocado. Al principio nombra la regla en voz alta (\"la tinta, no la palabra\"), mant\xe9n los ojos en el rasgo objetivo en lugar de dejarlos derivar hacia el distractor, y una vez que la precisi\xf3n sea s\xf3lida, busca velocidad por igual en los ensayos congruentes e incongruentes.",duration:"Corto y frecuente supera a largo y espor\xe1dico. De cinco a diez minutos al d\xeda, unos cuantos d\xedas por semana, basta para construir y mantener una velocidad estable, y normalmente ver\xe1s que tu tiempo de reacci\xf3n se asienta dentro de la primera semana o dos.",research:"La evidencia es m\xe1s s\xf3lida justo para lo que cabr\xeda esperar: te vuelves medible m\xe1s r\xe1pido y preciso en las tareas de conflicto en s\xed, y el coste de la interferencia se reduce con la pr\xe1ctica. Las afirmaciones de que esto se traslada a la atenci\xf3n general, al autocontrol en la vida diaria o a la inteligencia son mucho m\xe1s d\xe9biles; los estudios controlados, incluido un ensayo de 2024 en ni\xf1os, hallan repetidamente poca transferencia cercana o lejana, as\xed que toma con cautela las grandes promesas.",rec:"Persigue primero una tasa de error baja y estable y deja que la velocidad venga despu\xe9s: una ronda r\xe1pida llena de errores entrena justo el reflejo que intentas suprimir.",faq:[["\xbfPor qu\xe9 sigo soltando la respuesta equivocada aunque me sepa la regla?","Porque leer una palabra o seguir un mont\xf3n de flechas es autom\xe1tico y r\xe1pido, mientras que aplicar la regla es deliberado y m\xe1s lento. Esa brecha es justo el sentido del ejercicio, y la pr\xe1ctica es lo que la estrecha."],["\xbfEsto me har\xe1 m\xe1s concentrado en la vida diaria?","Sinceramente, probablemente no de forma notable. Mejorar\xe1s con claridad en tareas de conflicto como esta, pero la investigaci\xf3n muestra que el traslado amplio a la concentraci\xf3n del mundo real es d\xe9bil y poco fiable, as\xed que disfr\xfatalo como pr\xe1ctica espec\xedfica y no como una cura para la distracci\xf3n."],["\xbfDebo apuntar a la velocidad o a la precisi\xf3n?","Primero la precisi\xf3n. Una vez que rara vez cometas errores, empuja con suavidad tu velocidad; perseguir la velocidad pura antes de eso solo te entrena para disparar la respuesta equivocada y autom\xe1tica."]],variants:"El Stroop de palabra-color, los flancos de flechas o letras con distractores a cada lado, y las versiones de n\xfameros donde el tama\xf1o entra en conflicto con el valor. Los modos m\xe1s dif\xedciles invierten la regla a mitad de partida, a\xf1aden un l\xedmite de tiempo o cambian qu\xe9 rasgo es el objetivo para que no puedas ir en piloto autom\xe1tico."},de:{about:"Attention Conflict zeigt dir einen Reiz, bei dem zwei Hinweise einander widersprechen, und deine Aufgabe ist es, auf den zu reagieren, der z\xe4hlt, und den zu ignorieren, der ablenkt. Ein klassisches Beispiel ist ein Farbwort, das in einer nicht passenden Tinte gedruckt ist, etwa das Wort ROT in Blau geschrieben, wobei du die Tinte benennen und nicht das Wort lesen musst, indem du so schnell und genau wie m\xf6glich auf die richtige Antwort tippst.",benefit:"Es trainiert die selektive Aufmerksamkeit und die Reaktionshemmung, die F\xe4higkeit, sich auf das relevante Merkmal einzuklinken und einen st\xe4rkeren, automatischeren Impuls zu \xfcberschreiben. Du \xfcbst den Moment, in dem du dich selbst erwischst, bevor die falsche, gewohnheitsm\xe4\xdfige Antwort herausrutscht.",history:"Das Genre ging aus zwei wegweisenden Experimenten der experimentellen Psychologie hervor. Die Farbwort-Version stammt aus John Ridley Stroops Interferenzstudien von 1935, und die Pfeil- und Buchstaben-Versionen stammen von der Flanker-Aufgabe ab, die Barbara und Charles Eriksen 1974 ver\xf6ffentlichten. Beide wurden zu Standardwerkzeugen der Aufmerksamkeitsforschung und wurden sp\xe4ter in unz\xe4hlige bildschirmbasierte Trainingsspiele \xfcbertragen.",creator:"Es gibt keinen einzelnen Erfinder genau dieses Spiels. Es geh\xf6rt zur Tradition der Konfliktaufgaben in der kognitiven Psychologie, deren beide bekannteste Urheber J. R. Stroop sind, der den Farbwort-Interferenzeffekt 1935 ver\xf6ffentlichte, sowie B. A. und C. W. Eriksen, die die Flanker-Aufgabe 1974 einf\xfchrten.",methods:"Werde gerade so viel langsamer, dass die Fehler niedrig bleiben, denn in Fehler hineinzuhetzen trainiert die falsche Gewohnheit. Benenne die Regel anfangs laut (\"Tinte, nicht Wort\"), halte den Blick auf dem Zielmerkmal, statt ihn zum Ablenker abdriften zu lassen, und strebe, sobald die Genauigkeit solide ist, bei kongruenten und inkongruenten Durchg\xe4ngen gleicherma\xdfen nach Tempo.",duration:"Kurz und h\xe4ufig schl\xe4gt lang und selten. F\xfcnf bis zehn Minuten am Tag, ein paar Tage die Woche, reichen v\xf6llig, um ein stabiles Tempo aufzubauen und zu halten, und meist siehst du deine Reaktionszeit innerhalb der ersten ein, zwei Wochen einpendeln.",research:"Die Belege sind am st\xe4rksten f\xfcr genau das, was man erwarten w\xfcrde \u2014 du wirst messbar schneller und genauer bei Konfliktaufgaben selbst, und die Interferenzkosten schrumpfen mit \xdcbung. Behauptungen, dass sich das auf die allgemeine Aufmerksamkeit, die Selbstkontrolle im Alltag oder die Intelligenz \xfcbertr\xe4gt, sind weit schw\xe4cher; kontrollierte Studien, darunter eine Studie von 2024 mit Kindern, finden wiederholt kaum nahen oder fernen Transfer, also begegne den gro\xdfen Versprechen mit Vorsicht.",rec:"Jage zuerst einer niedrigen, gleichm\xe4\xdfigen Fehlerquote nach und lass das Tempo folgen \u2014 ein schneller Durchlauf voller Fehler trainiert genau den Reflex, den du zu unterdr\xfccken versuchst.",faq:[["Warum platze ich immer wieder mit der falschen Antwort heraus, obwohl ich die Regel kenne?","Weil das Lesen eines Wortes oder das Folgen einer Schar von Pfeilen automatisch und schnell ist, w\xe4hrend das Anwenden der Regel bewusst und langsamer abl\xe4uft. Genau diese L\xfccke ist der ganze Sinn der \xdcbung, und das Training ist das, was sie verkleinert."],["Macht mich das im Alltag konzentrierter?","Ehrlich gesagt, wohl nicht in nennenswertem Ma\xdf. Du wirst klar besser bei Konfliktaufgaben wie dieser, aber die Forschung zeigt, dass eine breite \xdcbertragung auf reale Konzentration schwach und unzuverl\xe4ssig ist, also genie\xdfe es als gezieltes Training statt als Heilmittel gegen Ablenkung."],["Soll ich auf Tempo oder Genauigkeit zielen?","Genauigkeit zuerst. Sobald du nur noch selten Fehler machst, steigere behutsam dein Tempo; rohem Tempo davor hinterherzujagen, trainiert dich nur darauf, die falsche, automatische Antwort abzufeuern."]],variants:"Der Farbwort-Stroop, der Pfeil- oder Buchstaben-Flanker mit Ablenkern zu beiden Seiten sowie Zahlen-Versionen, bei denen die Gr\xf6\xdfe mit dem Zahlenwert in Konflikt ger\xe4t. Schwerere Modi kehren die Regel mitten im Spiel um, f\xfcgen ein Zeitlimit hinzu oder wechseln, welches Merkmal das Ziel ist, sodass du nicht auf Autopilot laufen kannst."},pt:{about:"Conflito de Aten\xe7\xe3o apresenta um est\xedmulo em que duas pistas se contradizem, e sua tarefa \xe9 responder \xe0quela que importa enquanto ignora a que distrai. Um exemplo cl\xe1ssico \xe9 uma palavra de cor impressa numa tinta que n\xe3o combina, como a palavra VERMELHO escrita em azul, em que voc\xea precisa nomear a tinta e n\xe3o ler a palavra, tocando na resposta certa o mais r\xe1pido e preciso que conseguir.",benefit:"Ele treina a aten\xe7\xe3o seletiva e a inibi\xe7\xe3o de resposta, a capacidade de se fixar na caracter\xedstica relevante e anular um impulso mais forte e autom\xe1tico. Voc\xea est\xe1 praticando o instante de se segurar antes que a resposta errada e habitual escape.",history:"O g\xeanero nasceu de dois experimentos marcantes da psicologia experimental. A vers\xe3o de palavra de cor vem dos estudos de interfer\xeancia de John Ridley Stroop, de 1935, e as vers\xf5es com setas e letras descendem da tarefa de flancos (flanker) publicada por Barbara e Charles Eriksen em 1974. Ambas se tornaram itens b\xe1sicos da pesquisa sobre aten\xe7\xe3o e foram depois adaptadas em incont\xe1veis jogos de treino em tela.",creator:"N\xe3o h\xe1 um \xfanico inventor deste jogo exato. Ele pertence \xe0 tradi\xe7\xe3o das tarefas de conflito na psicologia cognitiva, sendo os dois pais mais conhecidos J. R. Stroop, que publicou o efeito de interfer\xeancia palavra-cor em 1935, e B. A. e C. W. Eriksen, que introduziram a tarefa de flancos em 1974.",methods:"Reduza a velocidade s\xf3 o suficiente para manter os erros baixos, porque correr para o erro ensina o h\xe1bito errado. No come\xe7o, diga a regra em voz alta (\"a tinta, n\xe3o a palavra\"), mantenha os olhos na caracter\xedstica-alvo em vez de deix\xe1-los derivar para o distrator e, quando a precis\xe3o estiver firme, busque velocidade tanto nas tentativas congruentes quanto nas incongruentes.",duration:"Curto e frequente bate longo e raro. De cinco a dez minutos por dia, alguns dias por semana, j\xe1 basta para construir e manter uma velocidade est\xe1vel, e normalmente voc\xea ver\xe1 seu tempo de rea\xe7\xe3o se assentar dentro da primeira semana ou duas.",research:"As evid\xeancias s\xe3o mais fortes exatamente para o esperado \u2014 voc\xea fica mensuravelmente mais r\xe1pido e mais preciso nas pr\xf3prias tarefas de conflito, e o custo de interfer\xeancia encolhe com a pr\xe1tica. Alega\xe7\xf5es de que isso se transfere para a aten\xe7\xe3o geral, o autocontrole na vida di\xe1ria ou a intelig\xeancia s\xe3o bem mais fracas; estudos controlados, incluindo um ensaio de 2024 com crian\xe7as, repetidamente encontram pouca transfer\xeancia pr\xf3xima ou distante, ent\xe3o trate as grandes promessas com cautela.",rec:"Persiga primeiro uma taxa de erro baixa e est\xe1vel e deixe a velocidade vir depois \u2014 uma rodada r\xe1pida cheia de erros treina justamente o reflexo que voc\xea est\xe1 tentando suprimir.",faq:[["Por que eu vivo soltando a resposta errada mesmo sabendo a regra?","Porque ler uma palavra ou seguir uma fileira de setas \xe9 autom\xe1tico e r\xe1pido, enquanto aplicar a regra \xe9 deliberado e mais lento. Essa diferen\xe7a \xe9 justamente o objetivo do exerc\xedcio, e a pr\xe1tica \xe9 o que a estreita."],["Isso vai me deixar mais focado no dia a dia?","Honestamente, provavelmente n\xe3o de forma expressiva. Voc\xea claramente vai ficar melhor em tarefas de conflito como esta, mas as pesquisas mostram que a transfer\xeancia ampla para o foco no mundo real \xe9 fraca e pouco confi\xe1vel, ent\xe3o aproveite-a como pr\xe1tica direcionada, e n\xe3o como cura para a distra\xe7\xe3o."],["Devo buscar velocidade ou precis\xe3o?","Precis\xe3o primeiro. Quando voc\xea raramente errar, force suavemente a velocidade; perseguir velocidade pura antes disso s\xf3 te treina a disparar a resposta errada e autom\xe1tica."]],variants:"O Stroop de palavra-cor, a tarefa de flancos com setas ou letras com distratores dos dois lados, e vers\xf5es num\xe9ricas em que o tamanho conflita com o valor. Os modos mais dif\xedceis invertem a regra no meio do jogo, adicionam um limite de tempo ou trocam qual caracter\xedstica \xe9 o alvo, para que voc\xea n\xe3o consiga jogar no piloto autom\xe1tico."},hi:{about:"Attention Conflict \u0906\u092a\u0915\u094b \u090f\u0915 \u0910\u0938\u093e \u0909\u0926\u094d\u0926\u0940\u092a\u0915 \u0926\u093f\u0916\u093e\u0924\u093e \u0939\u0948 \u091c\u0939\u093e\u0901 \u0926\u094b \u0938\u0902\u0915\u0947\u0924 \u0906\u092a\u0938 \u092e\u0947\u0902 \u091f\u0915\u0930\u093e\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u0906\u092a\u0915\u093e \u0915\u093e\u092e \u0909\u0938 \u0938\u0902\u0915\u0947\u0924 \u092a\u0930 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0926\u0947\u0928\u093e \u0939\u0948 \u091c\u094b \u092e\u093e\u092f\u0928\u0947 \u0930\u0916\u0924\u093e \u0939\u0948, \u0914\u0930 \u0909\u0938 \u0938\u0902\u0915\u0947\u0924 \u0915\u094b \u0928\u091c\u093c\u0930\u0905\u0902\u0926\u093e\u091c\u093c \u0915\u0930\u0928\u093e \u0939\u0948 \u091c\u094b \u0927\u094d\u092f\u093e\u0928 \u092d\u091f\u0915\u093e\u0924\u093e \u0939\u0948\u0964 \u090f\u0915 \u091a\u093f\u0930-\u092a\u0930\u093f\u091a\u093f\u0924 \u0909\u0926\u093e\u0939\u0930\u0923 \u0939\u0948 \u0915\u093f\u0938\u0940 \u092c\u0947\u092e\u0947\u0932 \u0938\u094d\u092f\u093e\u0939\u0940 \u092e\u0947\u0902 \u091b\u092a\u093e \u0930\u0902\u0917 \u0915\u093e \u0928\u093e\u092e, \u091c\u0948\u0938\u0947 \"\u0932\u093e\u0932\" \u0936\u092c\u094d\u0926 \u0928\u0940\u0932\u0940 \u0938\u094d\u092f\u093e\u0939\u0940 \u092e\u0947\u0902 \u0932\u093f\u0916\u093e \u0939\u094b, \u091c\u0939\u093e\u0901 \u0906\u092a\u0915\u094b \u0938\u094d\u092f\u093e\u0939\u0940 \u0915\u093e \u0930\u0902\u0917 \u092c\u0924\u093e\u0928\u093e \u0939\u0948 \u0914\u0930 \u0936\u092c\u094d\u0926 \u0928\u0939\u0940\u0902 \u092a\u0922\u093c\u0928\u093e \u0939\u0948, \u0914\u0930 \u091c\u093f\u0924\u0928\u0940 \u0924\u0947\u091c\u093c\u0940 \u0914\u0930 \u0938\u091f\u0940\u0915\u0924\u093e \u0938\u0947 \u0939\u094b \u0938\u0915\u0947 \u0938\u0939\u0940 \u091c\u0935\u093e\u092c \u092a\u0930 \u091f\u0948\u092a \u0915\u0930\u0928\u093e \u0939\u0948\u0964",benefit:"\u092f\u0939 \u091a\u092f\u0928\u093e\u0924\u094d\u092e\u0915 \u0927\u094d\u092f\u093e\u0928 \u0914\u0930 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0905\u0935\u0930\u094b\u0927\u0928 \u0915\u094b \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u093f\u0924 \u0915\u0930\u0924\u093e \u0939\u0948 \u2014 \u092a\u094d\u0930\u093e\u0938\u0902\u0917\u093f\u0915 \u0935\u093f\u0936\u0947\u0937\u0924\u093e \u092a\u0930 \u091f\u093f\u0915 \u091c\u093e\u0928\u0947 \u0914\u0930 \u0915\u093f\u0938\u0940 \u092a\u094d\u0930\u092c\u0932, \u0905\u0927\u093f\u0915 \u0938\u094d\u0935\u0924\u0903\u091a\u093e\u0932\u093f\u0924 \u0906\u0935\u0947\u0917 \u0915\u094b \u0926\u092c\u093e \u0926\u0947\u0928\u0947 \u0915\u0940 \u0915\u094d\u0937\u092e\u0924\u093e\u0964 \u0906\u092a \u0920\u0940\u0915 \u0909\u0938 \u092a\u0932 \u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0930 \u0930\u0939\u0947 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902 \u091c\u092c \u0906\u092a \u0917\u0932\u0924, \u0906\u0926\u0924\u0928 \u091c\u0935\u093e\u092c \u0915\u0947 \u0928\u093f\u0915\u0932\u0928\u0947 \u0938\u0947 \u092a\u0939\u0932\u0947 \u0916\u093c\u0941\u0926 \u0915\u094b \u0925\u093e\u092e \u0932\u0947\u0924\u0947 \u0939\u0948\u0902\u0964",history:"\u092f\u0939 \u0935\u0930\u094d\u0917 \u092a\u094d\u0930\u093e\u092f\u094b\u0917\u093f\u0915 \u092e\u0928\u094b\u0935\u093f\u091c\u094d\u091e\u093e\u0928 \u0915\u0947 \u0926\u094b \u0910\u0924\u093f\u0939\u093e\u0938\u093f\u0915 \u092a\u094d\u0930\u092f\u094b\u0917\u094b\u0902 \u0938\u0947 \u0928\u093f\u0915\u0932\u093e\u0964 \u0930\u0902\u0917-\u0936\u092c\u094d\u0926 \u0935\u093e\u0932\u093e \u0930\u0942\u092a John Ridley Stroop \u0915\u0947 1935 \u0915\u0947 \u0935\u094d\u092f\u0924\u093f\u0915\u0930\u0923 \u0905\u0927\u094d\u092f\u092f\u0928\u094b\u0902 \u0938\u0947 \u0906\u0924\u093e \u0939\u0948, \u0914\u0930 \u0924\u0940\u0930 \u0924\u0925\u093e \u0905\u0915\u094d\u0937\u0930 \u0935\u093e\u0932\u0947 \u0930\u0942\u092a Barbara \u0914\u0930 Charles Eriksen \u0926\u094d\u0935\u093e\u0930\u093e 1974 \u092e\u0947\u0902 \u092a\u094d\u0930\u0915\u093e\u0936\u093f\u0924 \u092b\u094d\u0932\u0948\u0902\u0915\u0930 \u0915\u093e\u0930\u094d\u092f \u0938\u0947 \u0909\u0924\u0930\u0947 \u0939\u0948\u0902\u0964 \u0926\u094b\u0928\u094b\u0902 \u0927\u094d\u092f\u093e\u0928-\u0936\u094b\u0927 \u0915\u093e \u0905\u0928\u093f\u0935\u093e\u0930\u094d\u092f \u0939\u093f\u0938\u094d\u0938\u093e \u092c\u0928 \u0917\u090f \u0914\u0930 \u092c\u093e\u0926 \u092e\u0947\u0902 \u0905\u0928\u0917\u093f\u0928\u0924 \u0938\u094d\u0915\u094d\u0930\u0940\u0928-\u0906\u0927\u093e\u0930\u093f\u0924 \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u0916\u0947\u0932\u094b\u0902 \u092e\u0947\u0902 \u0922\u093e\u0932\u0947 \u0917\u090f\u0964",creator:"\u0907\u0938 \u0916\u093c\u093e\u0938 \u0916\u0947\u0932 \u0915\u093e \u0915\u094b\u0908 \u090f\u0915 \u0906\u0935\u093f\u0937\u094d\u0915\u093e\u0930\u0915 \u0928\u0939\u0940\u0902 \u0939\u0948\u0964 \u092f\u0939 \u0938\u0902\u091c\u094d\u091e\u093e\u0928\u093e\u0924\u094d\u092e\u0915 \u092e\u0928\u094b\u0935\u093f\u091c\u094d\u091e\u093e\u0928 \u0915\u0940 \u0926\u094d\u0935\u0902\u0926\u094d\u0935-\u0915\u093e\u0930\u094d\u092f \u092a\u0930\u0902\u092a\u0930\u093e \u0938\u0947 \u091c\u0941\u0921\u093c\u093e \u0939\u0948, \u091c\u093f\u0938\u0915\u0947 \u0926\u094b \u0938\u092c\u0938\u0947 \u092a\u094d\u0930\u0938\u093f\u0926\u094d\u0927 \u091c\u0928\u0915 \u0939\u0948\u0902 J. R. Stroop, \u091c\u093f\u0928\u094d\u0939\u094b\u0902\u0928\u0947 1935 \u092e\u0947\u0902 \u0930\u0902\u0917-\u0936\u092c\u094d\u0926 \u0935\u094d\u092f\u0924\u093f\u0915\u0930\u0923 \u092a\u094d\u0930\u092d\u093e\u0935 \u092a\u094d\u0930\u0915\u093e\u0936\u093f\u0924 \u0915\u093f\u092f\u093e, \u0914\u0930 B. A. \u0924\u0925\u093e C. W. Eriksen, \u091c\u093f\u0928\u094d\u0939\u094b\u0902\u0928\u0947 1974 \u092e\u0947\u0902 \u092b\u094d\u0932\u0948\u0902\u0915\u0930 \u0915\u093e\u0930\u094d\u092f \u092a\u0947\u0936 \u0915\u093f\u092f\u093e\u0964",methods:"\u092c\u0938 \u0907\u0924\u0928\u093e \u0927\u0940\u092e\u093e \u0939\u094b \u091c\u093e\u090f\u0901 \u0915\u093f \u0917\u0932\u0924\u093f\u092f\u093e\u0901 \u0915\u092e \u0930\u0939\u0947\u0902, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u0939\u0921\u093c\u092c\u0921\u093c\u0940 \u092e\u0947\u0902 \u0917\u0932\u0924\u093f\u092f\u093e\u0901 \u0915\u0930\u0928\u093e \u0917\u0932\u0924 \u0906\u0926\u0924 \u0938\u093f\u0916\u093e\u0924\u093e \u0939\u0948\u0964 \u0936\u0941\u0930\u0941\u0906\u0924 \u092e\u0947\u0902 \u0928\u093f\u092f\u092e \u091c\u093c\u094b\u0930 \u0938\u0947 \u092c\u094b\u0932\u0947\u0902 (\"\u0938\u094d\u092f\u093e\u0939\u0940, \u0936\u092c\u094d\u0926 \u0928\u0939\u0940\u0902\"), \u0905\u092a\u0928\u0940 \u0928\u091c\u093c\u0930 \u0932\u0915\u094d\u0937\u094d\u092f-\u0935\u093f\u0936\u0947\u0937\u0924\u093e \u092a\u0930 \u091f\u093f\u0915\u093e\u090f \u0930\u0916\u0947\u0902 \u092c\u091c\u093e\u092f \u0907\u0938\u0915\u0947 \u0915\u093f \u0935\u0939 \u0927\u094d\u092f\u093e\u0928 \u092d\u091f\u0915\u093e\u0928\u0947 \u0935\u093e\u0932\u0947 \u0915\u0940 \u0913\u0930 \u0938\u0930\u0915\u0947, \u0914\u0930 \u091c\u092c \u0938\u091f\u0940\u0915\u0924\u093e \u092a\u0915\u094d\u0915\u0940 \u0939\u094b \u091c\u093e\u090f, \u0924\u094b \u092e\u0947\u0932 \u0916\u093e\u0928\u0947 \u0935\u093e\u0932\u0947 \u0914\u0930 \u092c\u0947\u092e\u0947\u0932 \u0926\u094b\u0928\u094b\u0902 \u0924\u0930\u0939 \u0915\u0947 \u092a\u094d\u0930\u092f\u093e\u0938\u094b\u0902 \u092a\u0930 \u0938\u092e\u093e\u0928 \u0930\u0942\u092a \u0938\u0947 \u0930\u092b\u093c\u094d\u0924\u093e\u0930 \u092c\u0922\u093c\u093e\u090f\u0901\u0964",duration:"\u091b\u094b\u091f\u093e \u0914\u0930 \u092c\u093e\u0930-\u092c\u093e\u0930, \u0932\u0902\u092c\u0947 \u0914\u0930 \u0915\u092d\u0940-\u0915\u092d\u093e\u0930 \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u0939\u0948\u0964 \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u0915\u0941\u091b \u0926\u093f\u0928, \u0930\u094b\u091c\u093c \u092a\u093e\u0901\u091a \u0938\u0947 \u0926\u0938 \u092e\u093f\u0928\u091f, \u090f\u0915 \u0938\u094d\u0925\u093f\u0930 \u0930\u092b\u093c\u094d\u0924\u093e\u0930 \u092c\u0928\u093e\u0928\u0947 \u0914\u0930 \u092c\u0928\u093e\u090f \u0930\u0916\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0915\u093e\u092b\u093c\u0940 \u0939\u0948, \u0914\u0930 \u0906\u092e\u0924\u094c\u0930 \u092a\u0930 \u0906\u092a\u0915\u094b \u092a\u0939\u0932\u0947 \u090f\u0915-\u0926\u094b \u0939\u092b\u093c\u094d\u0924\u0947 \u0915\u0947 \u092d\u0940\u0924\u0930 \u0939\u0940 \u0905\u092a\u0928\u093e \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0938\u092e\u092f \u0925\u092e\u0924\u093e \u0926\u093f\u0916\u0947\u0917\u093e\u0964",research:"\u092a\u094d\u0930\u092e\u093e\u0923 \u0938\u092c\u0938\u0947 \u0920\u094b\u0938 \u0920\u0940\u0915 \u0909\u0938\u0940 \u092c\u093e\u0924 \u0915\u0947 \u0932\u093f\u090f \u0939\u0948\u0902 \u091c\u093f\u0938\u0915\u0940 \u0906\u092a \u0909\u092e\u094d\u092e\u0940\u0926 \u0915\u0930\u0947\u0902\u0917\u0947 \u2014 \u0906\u092a \u0916\u093c\u0941\u0926 \u0926\u094d\u0935\u0902\u0926\u094d\u0935-\u0915\u093e\u0930\u094d\u092f\u094b\u0902 \u092e\u0947\u0902 \u0928\u093e\u092a\u0928\u0947 \u0932\u093e\u092f\u0915 \u0924\u0947\u091c\u093c \u0914\u0930 \u0938\u091f\u0940\u0915 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0947 \u0938\u093e\u0925 \u0935\u094d\u092f\u0924\u093f\u0915\u0930\u0923 \u0915\u0940 \u0915\u0940\u092e\u0924 \u0918\u091f\u0924\u0940 \u0939\u0948\u0964 \u092f\u0947 \u0926\u093e\u0935\u0947 \u0915\u093f \u092f\u0939 \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u0927\u094d\u092f\u093e\u0928, \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0947 \u0906\u0924\u094d\u092e-\u0928\u093f\u092f\u0902\u0924\u094d\u0930\u0923 \u092f\u093e \u092c\u0941\u0926\u094d\u0927\u093f \u0924\u0915 \u092a\u0939\u0941\u0901\u091a\u0924\u093e \u0939\u0948, \u0915\u0939\u0940\u0902 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0915\u092e\u091c\u093c\u094b\u0930 \u0939\u0948\u0902; \u0928\u093f\u092f\u0902\u0924\u094d\u0930\u093f\u0924 \u0905\u0927\u094d\u092f\u092f\u0928, \u091c\u093f\u0928\u092e\u0947\u0902 \u092c\u091a\u094d\u091a\u094b\u0902 \u092a\u0930 2024 \u0915\u093e \u090f\u0915 \u092a\u0930\u0940\u0915\u094d\u0937\u0923 \u092d\u0940 \u0936\u093e\u092e\u093f\u0932 \u0939\u0948, \u092c\u093e\u0930-\u092c\u093e\u0930 \u092c\u0939\u0941\u0924 \u0915\u092e \u0928\u093f\u0915\u091f \u092f\u093e \u0926\u0942\u0930 \u0915\u093e \u0939\u0938\u094d\u0924\u093e\u0902\u0924\u0930\u0923 \u092a\u093e\u0924\u0947 \u0939\u0948\u0902, \u0907\u0938\u0932\u093f\u090f \u092c\u0921\u093c\u0947-\u092c\u0921\u093c\u0947 \u0935\u093e\u0926\u094b\u0902 \u0915\u094b \u0938\u093e\u0935\u0927\u093e\u0928\u0940 \u0938\u0947 \u0932\u0947\u0902\u0964",rec:"\u092a\u0939\u0932\u0947 \u090f\u0915 \u0915\u092e, \u0938\u094d\u0925\u093f\u0930 \u0924\u094d\u0930\u0941\u091f\u093f-\u0926\u0930 \u0915\u093e \u092a\u0940\u091b\u093e \u0915\u0930\u0947\u0902 \u0914\u0930 \u0930\u092b\u093c\u094d\u0924\u093e\u0930 \u0915\u094b \u0905\u092a\u0928\u0947 \u0906\u092a \u0906\u0928\u0947 \u0926\u0947\u0902 \u2014 \u0917\u0932\u0924\u093f\u092f\u094b\u0902 \u0938\u0947 \u092d\u0930\u0940 \u0924\u0947\u091c\u093c \u0926\u094c\u0921\u093c \u0920\u0940\u0915 \u0909\u0938\u0940 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0915\u094b \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u093f\u0924 \u0915\u0930\u0924\u0940 \u0939\u0948 \u091c\u093f\u0938\u0947 \u0906\u092a \u0926\u092c\u093e\u0928\u0947 \u0915\u0940 \u0915\u094b\u0936\u093f\u0936 \u0915\u0930 \u0930\u0939\u0947 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902\u0964",faq:[["\u092e\u0948\u0902 \u0928\u093f\u092f\u092e \u091c\u093e\u0928\u0924\u0947 \u0939\u0941\u090f \u092d\u0940 \u092c\u093e\u0930-\u092c\u093e\u0930 \u0917\u0932\u0924 \u091c\u0935\u093e\u092c \u0915\u094d\u092f\u094b\u0902 \u092c\u0915 \u0926\u0947\u0924\u093e \u0939\u0942\u0901?","\u0915\u094d\u092f\u094b\u0902\u0915\u093f \u0915\u094b\u0908 \u0936\u092c\u094d\u0926 \u092a\u0922\u093c\u0928\u093e \u092f\u093e \u0924\u0940\u0930\u094b\u0902 \u0915\u0940 \u092d\u0940\u0921\u093c \u0915\u093e \u092a\u0940\u091b\u093e \u0915\u0930\u0928\u093e \u0938\u094d\u0935\u0924\u0903\u091a\u093e\u0932\u093f\u0924 \u0914\u0930 \u0924\u0947\u091c\u093c \u0939\u094b\u0924\u093e \u0939\u0948, \u091c\u092c\u0915\u093f \u0928\u093f\u092f\u092e \u0932\u093e\u0917\u0942 \u0915\u0930\u0928\u093e \u091c\u093e\u0928-\u092c\u0942\u091d\u0915\u0930 \u0915\u093f\u092f\u093e \u091c\u093e\u0928\u0947 \u0935\u093e\u0932\u093e \u0914\u0930 \u0927\u0940\u092e\u093e\u0964 \u092f\u0939\u0940 \u092b\u093c\u093e\u0938\u0932\u093e \u0907\u0938 \u0915\u0938\u0930\u0924 \u0915\u093e \u092a\u0942\u0930\u093e \u092e\u0915\u0938\u0926 \u0939\u0948, \u0914\u0930 \u0905\u092d\u094d\u092f\u093e\u0938 \u0939\u0940 \u0909\u0938\u0947 \u0915\u092e \u0915\u0930\u0924\u093e \u0939\u0948\u0964"],["\u0915\u094d\u092f\u093e \u0907\u0938\u0938\u0947 \u092e\u0948\u0902 \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0940 \u091c\u093c\u093f\u0902\u0926\u0917\u0940 \u092e\u0947\u0902 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u090f\u0915\u093e\u0917\u094d\u0930 \u0939\u094b \u091c\u093e\u090a\u0901\u0917\u093e?","\u0938\u091a \u0915\u0939\u0947\u0902 \u0924\u094b \u0915\u093f\u0938\u0940 \u092c\u0921\u093c\u0947 \u092a\u0948\u092e\u093e\u0928\u0947 \u092a\u0930 \u0936\u093e\u092f\u0926 \u0928\u0939\u0940\u0902\u0964 \u0906\u092a \u0907\u0938 \u091c\u0948\u0938\u0947 \u0926\u094d\u0935\u0902\u0926\u094d\u0935-\u0915\u093e\u0930\u094d\u092f\u094b\u0902 \u092e\u0947\u0902 \u0938\u093e\u092b\u093c \u0924\u094c\u0930 \u092a\u0930 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u090f\u0901\u0917\u0947, \u092a\u0930 \u0936\u094b\u0927 \u0926\u093f\u0916\u093e\u0924\u093e \u0939\u0948 \u0915\u093f \u0905\u0938\u0932\u0940-\u0926\u0941\u0928\u093f\u092f\u093e \u0915\u0940 \u090f\u0915\u093e\u0917\u094d\u0930\u0924\u093e \u0924\u0915 \u0935\u094d\u092f\u093e\u092a\u0915 \u0939\u0938\u094d\u0924\u093e\u0902\u0924\u0930\u0923 \u0915\u092e\u091c\u093c\u094b\u0930 \u0914\u0930 \u0905\u0935\u093f\u0936\u094d\u0935\u0938\u0928\u0940\u092f \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0907\u0938\u0947 \u0927\u094d\u092f\u093e\u0928-\u092d\u091f\u0915\u093e\u0935 \u0915\u0947 \u0907\u0932\u093e\u091c \u0915\u0947 \u092c\u091c\u093e\u092f \u090f\u0915 \u0932\u0915\u094d\u0937\u093f\u0924 \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u0906\u0928\u0902\u0926 \u0932\u0947\u0902\u0964"],["\u092e\u0941\u091d\u0947 \u0930\u092b\u093c\u094d\u0924\u093e\u0930 \u092a\u0930 \u091c\u093c\u094b\u0930 \u0926\u0947\u0928\u093e \u091a\u093e\u0939\u093f\u090f \u092f\u093e \u0938\u091f\u0940\u0915\u0924\u093e \u092a\u0930?","\u092a\u0939\u0932\u0947 \u0938\u091f\u0940\u0915\u0924\u093e\u0964 \u091c\u092c \u0906\u092a \u0936\u093e\u092f\u0926 \u0939\u0940 \u0915\u092d\u0940 \u0917\u0932\u0924\u0940 \u0915\u0930\u0947\u0902, \u0924\u092c \u0927\u0940\u0930\u0947-\u0927\u0940\u0930\u0947 \u0905\u092a\u0928\u0940 \u0930\u092b\u093c\u094d\u0924\u093e\u0930 \u092c\u0922\u093c\u093e\u090f\u0901; \u0909\u0938\u0938\u0947 \u092a\u0939\u0932\u0947 \u0915\u094b\u0930\u0940 \u0930\u092b\u093c\u094d\u0924\u093e\u0930 \u0915\u093e \u092a\u0940\u091b\u093e \u0915\u0930\u0928\u093e \u092c\u0938 \u0906\u092a\u0915\u094b \u0917\u0932\u0924, \u0938\u094d\u0935\u0924\u0903\u091a\u093e\u0932\u093f\u0924 \u091c\u0935\u093e\u092c \u0926\u093e\u0917\u093c\u0928\u0947 \u0915\u0940 \u0906\u0926\u0924 \u0921\u093e\u0932 \u0926\u0947\u0924\u093e \u0939\u0948\u0964"]],variants:"\u0930\u0902\u0917-\u0936\u092c\u094d\u0926 Stroop, \u0926\u094b\u0928\u094b\u0902 \u0913\u0930 \u0927\u094d\u092f\u093e\u0928 \u092d\u091f\u0915\u093e\u0928\u0947 \u0935\u093e\u0932\u094b\u0902 \u0915\u0947 \u0938\u093e\u0925 \u0924\u0940\u0930 \u092f\u093e \u0905\u0915\u094d\u0937\u0930 \u092b\u094d\u0932\u0948\u0902\u0915\u0930, \u0914\u0930 \u0938\u0902\u0916\u094d\u092f\u093e \u0935\u093e\u0932\u0947 \u0930\u0942\u092a \u091c\u0939\u093e\u0901 \u092e\u093e\u092a \u092e\u093e\u0928 \u0938\u0947 \u091f\u0915\u0930\u093e\u0924\u093e \u0939\u0948\u0964 \u0915\u0920\u093f\u0928 \u092e\u094b\u0921 \u092c\u0940\u091a \u0916\u0947\u0932 \u092e\u0947\u0902 \u0928\u093f\u092f\u092e \u092a\u0932\u091f \u0926\u0947\u0924\u0947 \u0939\u0948\u0902, \u0938\u092e\u092f-\u0938\u0940\u092e\u093e \u091c\u094b\u0921\u093c \u0926\u0947\u0924\u0947 \u0939\u0948\u0902, \u092f\u093e \u092f\u0939 \u092c\u0926\u0932 \u0926\u0947\u0924\u0947 \u0939\u0948\u0902 \u0915\u093f \u0915\u094c\u0928-\u0938\u0940 \u0935\u093f\u0936\u0947\u0937\u0924\u093e \u0932\u0915\u094d\u0937\u094d\u092f \u0939\u0948 \u0924\u093e\u0915\u093f \u0906\u092a \u0938\u094d\u0935\u0924\u0903\u091a\u093e\u0932\u093f\u0924 \u0939\u094b\u0915\u0930 \u0928 \u091a\u0932 \u0938\u0915\u0947\u0902\u0964"},zh:{about:"\u300c\u6ce8\u610f\u51b2\u7a81\u300d\u4f1a\u7ed9\u4f60\u5448\u73b0\u4e00\u4e2a\u6709\u4e24\u6761\u7ebf\u7d22\u4e92\u76f8\u77db\u76fe\u7684\u523a\u6fc0\uff0c\u4f60\u7684\u4efb\u52a1\u662f\u5bf9\u90a3\u6761\u8981\u7d27\u7684\u7ebf\u7d22\u4f5c\u51fa\u53cd\u5e94\uff0c\u540c\u65f6\u5ffd\u7565\u90a3\u6761\u6765\u6363\u4e71\u7684\u7ebf\u7d22\u3002\u4e00\u4e2a\u7ecf\u5178\u7684\u4f8b\u5b50\u662f\uff1a\u4e00\u4e2a\u989c\u8272\u8bcd\u88ab\u5370\u6210\u4e86\u4e0e\u4e4b\u4e0d\u7b26\u7684\u58a8\u6c34\u8272\uff0c\u6bd4\u5982\u300c\u7ea2\u300d\u8fd9\u4e2a\u5b57\u662f\u7528\u84dd\u8272\u5199\u7684\uff0c\u8fd9\u65f6\u4f60\u5fc5\u987b\u8bf4\u51fa\u58a8\u6c34\u7684\u989c\u8272\u800c\u4e0d\u662f\u8bfb\u51fa\u8fd9\u4e2a\u5b57\uff0c\u5e76\u5c3d\u53ef\u80fd\u53c8\u5feb\u53c8\u51c6\u5730\u70b9\u9009\u6b63\u786e\u7b54\u6848\u3002",benefit:"\u5b83\u8bad\u7ec3\u9009\u62e9\u6027\u6ce8\u610f\u548c\u53cd\u5e94\u6291\u5236\u2014\u2014\u4e5f\u5c31\u662f\u9501\u5b9a\u76f8\u5173\u7279\u5f81\u3001\u5e76\u538b\u5236\u4e00\u4e2a\u66f4\u5f3a\u3001\u66f4\u81ea\u52a8\u7684\u51b2\u52a8\u7684\u80fd\u529b\u3002\u4f60\u7ec3\u7684\uff0c\u6b63\u662f\u5728\u90a3\u4e2a\u9519\u8bef\u7684\u3001\u4e60\u60ef\u6027\u7684\u7b54\u6848\u8131\u53e3\u800c\u51fa\u4e4b\u524d\u628a\u81ea\u5df1\u62fd\u4f4f\u7684\u90a3\u4e00\u77ac\u95f4\u3002",history:"\u8fd9\u4e00\u7c7b\u9898\u578b\u8131\u80ce\u4e8e\u5b9e\u9a8c\u5fc3\u7406\u5b66\u4e2d\u4e24\u4e2a\u91cc\u7a0b\u7891\u5f0f\u7684\u5b9e\u9a8c\u3002\u989c\u8272\u8bcd\u7248\u672c\u6765\u81ea\u7ea6\u7ff0\xb7\u91cc\u5fb7\u5229\xb7\u65af\u7279\u9c81\u666e\uff08John Ridley Stroop\uff091935\u5e74\u7684\u5e72\u6270\u7814\u7a76\uff0c\u800c\u7bad\u5934\u548c\u5b57\u6bcd\u7248\u672c\u5219\u6e90\u81ea\u82ad\u82ad\u62c9\xb7\u57c3\u91cc\u514b\u68ee\uff08Barbara Eriksen\uff09\u4e0e\u67e5\u5c14\u65af\xb7\u57c3\u91cc\u514b\u68ee\uff08Charles Eriksen\uff09\u4e8e1974\u5e74\u53d1\u8868\u7684\u4fa7\u6291\u5236\uff08flanker\uff09\u4efb\u52a1\u3002\u4e24\u8005\u90fd\u6210\u4e86\u6ce8\u610f\u7814\u7a76\u4e2d\u7684\u5e38\u5907\u5de5\u5177\uff0c\u540e\u6765\u53c8\u88ab\u6539\u7f16\u6210\u6570\u4e0d\u80dc\u6570\u7684\u5c4f\u5e55\u8bad\u7ec3\u6e38\u620f\u3002",creator:"\u8fd9\u4e00\u6b3e\u5177\u4f53\u7684\u6e38\u620f\u6ca1\u6709\u5355\u4e00\u7684\u53d1\u660e\u8005\u3002\u5b83\u5c5e\u4e8e\u8ba4\u77e5\u5fc3\u7406\u5b66\u4e2d\u7684\u51b2\u7a81\u4efb\u52a1\u4f20\u7edf\uff0c\u5176\u4e2d\u6700\u5e7f\u4e3a\u4eba\u77e5\u7684\u4e24\u4f4d\u300c\u6e90\u5934\u300d\u662f\uff1aJ\xb7R\xb7\u65af\u7279\u9c81\u666e\uff08J. R. Stroop\uff09\uff0c\u4ed6\u4e8e1935\u5e74\u53d1\u8868\u4e86\u989c\u8272\u8bcd\u5e72\u6270\u6548\u5e94\uff1b\u4ee5\u53ca B\xb7A\xb7\u57c3\u91cc\u514b\u68ee\u548c C\xb7W\xb7\u57c3\u91cc\u514b\u68ee\uff08B. A. & C. W. Eriksen\uff09\uff0c\u4ed6\u4eec\u4e8e1974\u5e74\u5f15\u5165\u4e86\u4fa7\u6291\u5236\u4efb\u52a1\u3002",methods:"\u628a\u901f\u5ea6\u653e\u6162\u5230\u521a\u597d\u80fd\u8ba9\u9519\u8bef\u7ef4\u6301\u5728\u4f4e\u4f4d\u7684\u7a0b\u5ea6\uff0c\u56e0\u4e3a\u4e00\u5934\u624e\u8fdb\u9519\u8bef\u91cc\uff0c\u7ec3\u51fa\u6765\u7684\u662f\u574f\u4e60\u60ef\u3002\u4e00\u5f00\u59cb\u628a\u89c4\u5219\u5927\u58f0\u8bf4\u51fa\u6765\uff08\u300c\u770b\u58a8\u6c34\uff0c\u4e0d\u662f\u770b\u5b57\u300d\uff09\uff0c\u8ba9\u76ee\u5149\u505c\u5728\u76ee\u6807\u7279\u5f81\u4e0a\uff0c\u800c\u4e0d\u8981\u4efb\u7531\u5b83\u98d8\u5411\u5e72\u6270\u7269\uff1b\u7b49\u51c6\u786e\u7387\u7a33\u56fa\u4e4b\u540e\uff0c\u518d\u5728\u4e00\u81f4\u4e0e\u4e0d\u4e00\u81f4\u7684\u8bd5\u6b21\u4e0a\u4e00\u5e76\u53bb\u51b2\u901f\u5ea6\u3002",duration:"\u77ed\u800c\u9891\u7e41\u80dc\u8fc7\u957f\u800c\u7a00\u758f\u3002\u6bcf\u5929\u4e94\u5230\u5341\u5206\u949f\u3001\u6bcf\u5468\u7ec3\u51e0\u5929\uff0c\u5c31\u8db3\u4ee5\u5efa\u7acb\u5e76\u4fdd\u6301\u4e00\u4e2a\u7a33\u5b9a\u7684\u901f\u5ea6\uff0c\u800c\u4e14\u4f60\u901a\u5e38\u4f1a\u770b\u5230\u81ea\u5df1\u7684\u53cd\u5e94\u65f6\u95f4\u5728\u5934\u4e00\u4e24\u5468\u5185\u5c31\u7a33\u5b9a\u4e0b\u6765\u3002",research:"\u8bc1\u636e\u6700\u624e\u5b9e\u7684\uff0c\u6070\u6070\u662f\u4f60\u80fd\u9884\u6599\u5230\u7684\u90a3\u4e00\u70b9\u2014\u2014\u4f60\u4f1a\u5728\u51b2\u7a81\u4efb\u52a1\u672c\u8eab\u4e0a\u660e\u663e\u53d8\u5f97\u66f4\u5feb\u3001\u66f4\u51c6\uff0c\u800c\u90a3\u4efd\u300c\u5e72\u6270\u4ee3\u4ef7\u300d\u4e5f\u4f1a\u968f\u7ec3\u4e60\u800c\u7f29\u5c0f\u3002\u81f3\u4e8e\u8bf4\u8fd9\u80fd\u8fc1\u79fb\u5230\u4e00\u822c\u6ce8\u610f\u529b\u3001\u65e5\u5e38\u751f\u6d3b\u4e2d\u7684\u81ea\u63a7\u6216\u667a\u529b\u4e0a\uff0c\u8fd9\u7c7b\u8bf4\u6cd5\u5219\u8981\u8584\u5f31\u5f97\u591a\uff1b\u5305\u62ec2024\u5e74\u4e00\u9879\u4ee5\u513f\u7ae5\u4e3a\u5bf9\u8c61\u7684\u8bd5\u9a8c\u5728\u5185\u7684\u5bf9\u7167\u7814\u7a76\u53cd\u590d\u53d1\u73b0\uff0c\u8fd1\u8fc1\u79fb\u548c\u8fdc\u8fc1\u79fb\u90fd\u5fae\u4e4e\u5176\u5fae\uff0c\u6240\u4ee5\u5bf9\u90a3\u4e9b\u5b8f\u5927\u7684\u627f\u8bfa\u8981\u4fdd\u6301\u8c28\u614e\u3002",rec:"\u5148\u53bb\u8ffd\u6c42\u4e00\u4e2a\u4f4e\u800c\u7a33\u5b9a\u7684\u9519\u8bef\u7387\uff0c\u8ba9\u901f\u5ea6\u968f\u540e\u8ddf\u4e0a\u2014\u2014\u4e00\u6b21\u6ee1\u662f\u9519\u8bef\u7684\u5feb\u901f\u4f5c\u7b54\uff0c\u6070\u6070\u7ec3\u7684\u662f\u4f60\u6b63\u60f3\u538b\u5236\u7684\u90a3\u4e2a\u53cd\u5c04\u3002",faq:[["\u4e3a\u4ec0\u4e48\u660e\u660e\u77e5\u9053\u89c4\u5219\uff0c\u6211\u5374\u8fd8\u662f\u8001\u628a\u9519\u8bef\u7b54\u6848\u8131\u53e3\u8bf4\u51fa\u6765\uff1f","\u56e0\u4e3a\u8bfb\u4e00\u4e2a\u5b57\u3001\u6216\u987a\u7740\u4e00\u6392\u7bad\u5934\u8d70\uff0c\u662f\u81ea\u52a8\u800c\u5feb\u901f\u7684\uff0c\u800c\u5957\u7528\u89c4\u5219\u5374\u662f\u523b\u610f\u800c\u8f83\u6162\u7684\u3002\u8fd9\u6761\u300c\u65f6\u95f4\u5dee\u300d\u6b63\u662f\u8fd9\u9879\u7ec3\u4e60\u7684\u5168\u90e8\u610f\u4e49\u6240\u5728\uff0c\u800c\u7ec3\u4e60\u8981\u505a\u7684\uff0c\u5c31\u662f\u53bb\u7f29\u5c0f\u5b83\u3002"],["\u8fd9\u4f1a\u8ba9\u6211\u5728\u65e5\u5e38\u751f\u6d3b\u4e2d\u66f4\u4e13\u6ce8\u5417\uff1f","\u8001\u5b9e\u8bf4\uff0c\u5927\u6982\u4e0d\u4f1a\u6709\u592a\u5927\u5e45\u5ea6\u3002\u4f60\u4f1a\u660e\u663e\u66f4\u64c5\u957f\u8fd9\u4e00\u7c7b\u51b2\u7a81\u4efb\u52a1\uff0c\u4f46\u7814\u7a76\u8868\u660e\uff0c\u5b83\u5411\u73b0\u5b9e\u4e16\u754c\u4e13\u6ce8\u529b\u7684\u5e7f\u6cdb\u8fc1\u79fb\u662f\u8584\u5f31\u4e14\u4e0d\u53ef\u9760\u7684\uff0c\u6240\u4ee5\u8bf7\u628a\u5b83\u5f53\u4f5c\u4e00\u79cd\u6709\u9488\u5bf9\u6027\u7684\u7ec3\u4e60\u6765\u4eab\u53d7\uff0c\u800c\u4e0d\u662f\u6cbb\u6108\u5206\u5fc3\u7684\u826f\u65b9\u3002"],["\u6211\u8be5\u8ffd\u6c42\u901f\u5ea6\u8fd8\u662f\u51c6\u786e\uff1f","\u51c6\u786e\u4f18\u5148\u3002\u7b49\u4f60\u5f88\u5c11\u72af\u9519\u4e86\uff0c\u518d\u7f13\u7f13\u53bb\u63a8\u901f\u5ea6\uff1b\u5728\u90a3\u4e4b\u524d\u5c31\u4e00\u5473\u8ffd\u6c42\u7eaf\u901f\u5ea6\uff0c\u53ea\u4f1a\u628a\u4f60\u8bad\u7ec3\u6210\u62a2\u7740\u6253\u51fa\u90a3\u4e2a\u9519\u8bef\u7684\u3001\u81ea\u52a8\u7684\u53cd\u5e94\u3002"]],variants:"\u5305\u62ec\uff1a\u989c\u8272\u8bcd\u65af\u7279\u9c81\u666e\u3001\u4e24\u4fa7\u5e26\u5e72\u6270\u7269\u7684\u7bad\u5934\u6216\u5b57\u6bcd\u4fa7\u6291\u5236\u4efb\u52a1\uff0c\u4ee5\u53ca\u5927\u5c0f\u4e0e\u6570\u503c\u76f8\u51b2\u7a81\u7684\u6570\u5b57\u7248\u672c\u3002\u66f4\u96be\u7684\u6a21\u5f0f\u4f1a\u5728\u4e2d\u9014\u7ffb\u8f6c\u89c4\u5219\u3001\u52a0\u4e0a\u65f6\u95f4\u9650\u5236\uff0c\u6216\u5207\u6362\u54ea\u4e2a\u7279\u5f81\u624d\u662f\u76ee\u6807\uff0c\u8ba9\u4f60\u65e0\u6cd5\u9760\u60ef\u6027\u81ea\u52a8\u4f5c\u7b54\u3002"}},bart:{ru:{about:"BART: \u0420\u0438\u0441\u043a\u043e\u0432\u044b\u0439 \u0448\u0430\u0440 \u2014 \u0438\u0433\u0440\u0430 \u043d\u0430 \u043f\u0440\u0438\u043d\u044f\u0442\u0438\u0435 \u0440\u0435\u0448\u0435\u043d\u0438\u0439 \u043f\u043e \u043c\u043e\u0442\u0438\u0432\u0430\u043c Balloon Analogue Risk Task. \u0412\u044b \u043d\u0430\u0434\u0443\u0432\u0430\u0435\u0442\u0435 \u0432\u0438\u0440\u0442\u0443\u0430\u043b\u044c\u043d\u044b\u0439 \u0448\u0430\u0440 \u043f\u043e \u043e\u0434\u043d\u043e\u043c\u0443 \u043d\u0430\u0436\u0430\u0442\u0438\u044e: \u043a\u0430\u0436\u0434\u043e\u0435 \u043d\u0430\u0436\u0430\u0442\u0438\u0435 \u0434\u043e\u0431\u0430\u0432\u043b\u044f\u0435\u0442 \u0434\u0435\u043d\u044c\u0433\u0438 \u0432\u043e \u0432\u0440\u0435\u043c\u0435\u043d\u043d\u0443\u044e \u043a\u043e\u043f\u0438\u043b\u043a\u0443, \u043d\u043e \u0438 \u043f\u043e\u0432\u044b\u0448\u0430\u0435\u0442 \u0448\u0430\u043d\u0441, \u0447\u0442\u043e \u0448\u0430\u0440 \u043b\u043e\u043f\u043d\u0435\u0442. \u0412 \u043b\u044e\u0431\u043e\u0439 \u043c\u043e\u043c\u0435\u043d\u0442 \u043c\u043e\u0436\u043d\u043e \u0437\u0430\u0431\u0440\u0430\u0442\u044c \u043d\u0430\u043a\u043e\u043f\u043b\u0435\u043d\u043d\u043e\u0435, \u0430 \u043c\u043e\u0436\u043d\u043e \u0440\u0438\u0441\u043a\u043d\u0443\u0442\u044c \u0438 \u043a\u0430\u0447\u043d\u0443\u0442\u044c \u0435\u0449\u0451 \u2014 \u0435\u0441\u043b\u0438 \u0448\u0430\u0440 \u043b\u043e\u043f\u043d\u0435\u0442 \u0440\u0430\u043d\u044c\u0448\u0435, \u0432\u0441\u0451 \u0432 \u044d\u0442\u043e\u043c \u0440\u0430\u0443\u043d\u0434\u0435 \u0441\u0433\u043e\u0440\u0430\u0435\u0442.",benefit:"\u0422\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u043e\u0446\u0435\u043d\u043a\u0443 \u0440\u0438\u0441\u043a\u0430 \u0432 \u043d\u0435\u043e\u043f\u0440\u0435\u0434\u0435\u043b\u0451\u043d\u043d\u043e\u0441\u0442\u0438: \u043a\u0430\u043a \u0432\u0437\u0432\u0435\u0441\u0438\u0442\u044c \u0440\u0430\u0441\u0442\u0443\u0449\u0443\u044e \u043d\u0430\u0433\u0440\u0430\u0434\u0443 \u043f\u0440\u043e\u0442\u0438\u0432 \u0440\u0430\u0441\u0442\u0443\u0449\u0435\u0433\u043e \u0448\u0430\u043d\u0441\u0430 \u043f\u043e\u0442\u0435\u0440\u0438 \u0438 \u0432\u043e\u0432\u0440\u0435\u043c\u044f \u043e\u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u044c\u0441\u044f. \u0417\u0430\u043e\u0434\u043d\u043e \u043f\u0440\u043e\u043a\u0430\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044f \u0447\u0443\u0432\u0441\u0442\u0432\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c \u043a \u0432\u043e\u0437\u043d\u0430\u0433\u0440\u0430\u0436\u0434\u0435\u043d\u0438\u044e \u0438 \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044c \u0438\u043c\u043f\u0443\u043b\u044c\u0441\u0430 \u2014 \u0432\u0435\u0434\u044c \u0443\u043c\u043d\u044b\u0439 \u0445\u043e\u0434 \u0432 \u0442\u043e\u043c, \u0447\u0442\u043e\u0431\u044b \u0437\u0430\u0431\u0440\u0430\u0442\u044c \u0432\u044b\u0438\u0433\u0440\u044b\u0448 \u0434\u043e \u0442\u043e\u0433\u043e, \u043a\u0430\u043a \u0436\u0430\u0434\u043d\u043e\u0441\u0442\u044c \u0441\u043f\u0430\u043b\u0438\u0442 \u0440\u0430\u0443\u043d\u0434.",history:"\u0417\u0430\u0434\u0430\u0447\u0430 \u0440\u043e\u0434\u0438\u043b\u0430\u0441\u044c \u0432 \u0430\u043a\u0430\u0434\u0435\u043c\u0438\u0447\u0435\u0441\u043a\u043e\u0439 \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u0438 \u0432 \u043d\u0430\u0447\u0430\u043b\u0435 2000-\u0445 \u043a\u0430\u043a \u043f\u043e\u0432\u0435\u0434\u0435\u043d\u0447\u0435\u0441\u043a\u0430\u044f \u0430\u043b\u044c\u0442\u0435\u0440\u043d\u0430\u0442\u0438\u0432\u0430 \u043e\u043f\u0440\u043e\u0441\u043d\u0438\u043a\u0430\u043c \u043f\u0440\u043e \u0440\u0438\u0441\u043a, \u0433\u0434\u0435 \u043b\u044e\u0434\u0438 \u0447\u0430\u0441\u0442\u043e \u043f\u0440\u0438\u0443\u043a\u0440\u0430\u0448\u0438\u0432\u0430\u044e\u0442 \u0441\u0432\u043e\u044e \u043e\u0441\u0442\u043e\u0440\u043e\u0436\u043d\u043e\u0441\u0442\u044c. \u041e\u043d\u0430 \u0431\u044b\u0441\u0442\u0440\u043e \u0440\u0430\u0437\u043e\u0448\u043b\u0430\u0441\u044c \u043f\u043e \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u044f\u043c \u0437\u0430\u0432\u0438\u0441\u0438\u043c\u043e\u0441\u0442\u0435\u0439, \u0438\u043c\u043f\u0443\u043b\u044c\u0441\u0438\u0432\u043d\u043e\u0441\u0442\u0438 \u0438 \u043f\u043e\u0434\u0440\u043e\u0441\u0442\u043a\u043e\u0432, \u043e\u0431\u0437\u0430\u0432\u0435\u043b\u0430\u0441\u044c \u0432\u0435\u0440\u0441\u0438\u0435\u0439 \u0434\u043b\u044f \u043f\u043e\u0434\u0440\u043e\u0441\u0442\u043a\u043e\u0432 (BART-Y), \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u0438\u043c \u0438 \u043d\u0435\u0439\u0440\u043e\u0432\u0438\u0437\u0443\u0430\u043b\u0438\u0437\u0430\u0446\u0438\u043e\u043d\u043d\u044b\u043c \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u0430\u043c\u0438 \u0438 \u0441\u043e \u0432\u0440\u0435\u043c\u0435\u043d\u0435\u043c \u043f\u0440\u0435\u0432\u0440\u0430\u0442\u0438\u043b\u0430\u0441\u044c \u0432 \u043f\u043e\u043f\u0443\u043b\u044f\u0440\u043d\u043e\u0435 \u0438\u0433\u0440\u043e\u0432\u043e\u0435 \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u0435.",creator:"\u0415\u0451 \u0440\u0430\u0437\u0440\u0430\u0431\u043e\u0442\u0430\u043b \u041a\u0430\u0440\u043b \u041b\u0435\u0436\u0443\u044d\u0437 \u0441 \u043a\u043e\u043b\u043b\u0435\u0433\u0430\u043c\u0438 \u0432 \u0423\u043d\u0438\u0432\u0435\u0440\u0441\u0438\u0442\u0435\u0442\u0435 \u041c\u044d\u0440\u0438\u043b\u0435\u043d\u0434\u0430 \u0438 \u0432\u043f\u0435\u0440\u0432\u044b\u0435 \u043e\u043f\u0443\u0431\u043b\u0438\u043a\u043e\u0432\u0430\u043b \u0432 2002 \u0433\u043e\u0434\u0443 \u0432 \u0436\u0443\u0440\u043d\u0430\u043b\u0435 Journal of Experimental Psychology: Applied. \u041f\u043e \u0441\u043b\u043e\u0432\u0430\u043c \u041b\u0435\u0436\u0443\u044d\u0437\u0430, \u0438\u0434\u0435\u044f \u043f\u0440\u0438\u0448\u043b\u0430, \u043a\u043e\u0433\u0434\u0430 \u043e\u043d \u043d\u0430\u0431\u043b\u044e\u0434\u0430\u043b, \u043a\u0430\u043a \u043b\u044e\u0434\u0438 \u043d\u0430\u0434\u0443\u0432\u0430\u044e\u0442 \u0448\u0430\u0440\u044b \u043d\u0430 \u044f\u0440\u043c\u0430\u0440\u043a\u0435: \u043e\u0434\u043d\u0438 \u043e\u0441\u0442\u0430\u043d\u0430\u0432\u043b\u0438\u0432\u0430\u044e\u0442\u0441\u044f \u0437\u0430\u0440\u0430\u043d\u0435\u0435, \u0434\u0440\u0443\u0433\u0438\u0435 \u043a\u0430\u0447\u0430\u044e\u0442, \u043f\u043e\u043a\u0430 \u043d\u0435 \u043b\u043e\u043f\u043d\u0435\u0442.",methods:"\u0420\u0435\u0448\u0430\u0439\u0442\u0435, \u0434\u043e \u0441\u043a\u043e\u043b\u044c\u043a\u0438\u0445 \u043d\u0430\u0436\u0430\u0442\u0438\u0439 \u0434\u043e\u0439\u0434\u0451\u0442\u0435, \u0435\u0449\u0451 \u0434\u043e \u043d\u0430\u0447\u0430\u043b\u0430 \u0448\u0430\u0440\u0430, \u0438 \u0437\u0430\u0431\u0438\u0440\u0430\u0439\u0442\u0435 \u043e\u043a\u043e\u043b\u043e \u044d\u0442\u043e\u0439 \u0446\u0438\u0444\u0440\u044b, \u0430 \u043d\u0435 \u0440\u0435\u0430\u0433\u0438\u0440\u0443\u0439\u0442\u0435 \u043f\u043e\u0441\u043b\u0435 \u043a\u0430\u0436\u0434\u043e\u0433\u043e \u043a\u0430\u0447\u043a\u0430. \u041f\u0440\u0438\u043a\u0438\u0434\u044b\u0432\u0430\u0439\u0442\u0435, \u043d\u0430 \u043a\u0430\u043a\u043e\u043c \u043f\u0440\u0438\u043c\u0435\u0440\u043d\u043e \u043d\u0430\u0436\u0430\u0442\u0438\u0438 \u0448\u0430\u0440\u044b \u043e\u0431\u044b\u0447\u043d\u043e \u043b\u043e\u043f\u0430\u044e\u0442\u0441\u044f, \u0438 \u0446\u0435\u043b\u044c\u0441\u044f \u0447\u0443\u0442\u044c \u043d\u0438\u0436\u0435; \u0438 \u043d\u0435 \u043e\u0442\u044b\u0433\u0440\u044b\u0432\u0430\u0439\u0442\u0435\u0441\u044c \u043f\u043e\u0441\u043b\u0435 \u0432\u0437\u0440\u044b\u0432\u0430, \u043a\u0430\u0447\u0430\u044f \u0437\u043b\u0435\u0435 \u2014 \u0438\u043c\u0435\u043d\u043d\u043e \u0432 \u044d\u0442\u043e\u0442 \u043c\u043e\u043c\u0435\u043d\u0442 \u043b\u044e\u0434\u0435\u0439 \u0438 \u0437\u0430\u043d\u043e\u0441\u0438\u0442.",duration:"\u041b\u0443\u0447\u0448\u0435 \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u0435 \u043f\u043e\u0434\u0445\u043e\u0434\u044b: 20-40 \u0448\u0430\u0440\u043e\u0432, \u043f\u044f\u0442\u044c-\u0434\u0435\u0441\u044f\u0442\u044c \u043c\u0438\u043d\u0443\u0442 \u2014 \u0432\u043f\u043e\u043b\u043d\u0435 \u0434\u043e\u0441\u0442\u0430\u0442\u043e\u0447\u043d\u043e. \u041e\u0442\u043d\u043e\u0441\u0438\u0442\u0435\u0441\u044c \u043a \u044d\u0442\u043e\u043c\u0443 \u043a\u0430\u043a \u043a \u0440\u0435\u0434\u043a\u043e\u0439 \u0440\u0430\u0437\u043c\u0438\u043d\u043a\u0435 \u043d\u0430 \u0440\u0435\u0448\u0435\u043d\u0438\u044f \u043f\u0430\u0440\u0443 \u0440\u0430\u0437 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e, \u0430 \u043d\u0435 \u043a\u0430\u043a \u043a \u0435\u0436\u0435\u0434\u043d\u0435\u0432\u043d\u043e\u0439 \u0434\u043e\u043b\u0431\u0451\u0436\u043a\u0435.",research:"\u0421\u0438\u043b\u044c\u043d\u0435\u0435 \u0432\u0441\u0435\u0433\u043e \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043d\u043e \u043e\u0436\u0438\u0434\u0430\u0435\u043c\u043e\u0435: \u0437\u0430\u0434\u0430\u0447\u0430 \u043d\u0430\u0434\u0451\u0436\u043d\u043e \u0438\u0437\u043c\u0435\u0440\u044f\u0435\u0442 \u0441\u043a\u043b\u043e\u043d\u043d\u043e\u0441\u0442\u044c \u043a \u0440\u0438\u0441\u043a\u0443 \u0432 \u043b\u0430\u0431\u043e\u0440\u0430\u0442\u043e\u0440\u0438\u0438, \u0438\u043c\u0435\u0435\u0442 \u043f\u0440\u0438\u0435\u043c\u043b\u0435\u043c\u0443\u044e \u043f\u043e\u0432\u0442\u043e\u0440\u043d\u0443\u044e \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0438\u043c\u043e\u0441\u0442\u044c, \u0430 \u0447\u0438\u0441\u043b\u043e \u043d\u0430\u0436\u0430\u0442\u0438\u0439 \u0443\u043c\u0435\u0440\u0435\u043d\u043d\u043e \u0441\u0432\u044f\u0437\u0430\u043d\u043e \u0441 \u043d\u0435\u043a\u043e\u0442\u043e\u0440\u044b\u043c\u0438 \u0440\u0435\u0430\u043b\u044c\u043d\u044b\u043c\u0438 \u043f\u0440\u0438\u0432\u044b\u0447\u043a\u0430\u043c\u0438 \u2014 \u043a\u0443\u0440\u0435\u043d\u0438\u0435\u043c, \u043d\u0430\u0440\u043a\u043e\u0442\u0438\u043a\u0430\u043c\u0438, \u0430\u0437\u0430\u0440\u0442\u043d\u044b\u043c\u0438 \u0438\u0433\u0440\u0430\u043c\u0438. \u041d\u043e \u0441\u0432\u044f\u0437\u044c \u0441 \u0440\u0435\u0430\u043b\u044c\u043d\u044b\u043c\u0438 \u0436\u0438\u0437\u043d\u0435\u043d\u043d\u044b\u043c\u0438 \u0440\u0435\u0448\u0435\u043d\u0438\u044f\u043c\u0438 \u0441\u043b\u0430\u0431\u0430\u044f \u0438 \u043d\u0435\u0443\u0441\u0442\u043e\u0439\u0447\u0438\u0432\u0430\u044f, \u0441\u043e\u0433\u043b\u0430\u0441\u0438\u0435 \u0441 \u043e\u043f\u0440\u043e\u0441\u043d\u0438\u043a\u0430\u043c\u0438 \u043f\u0440\u043e \u0440\u0438\u0441\u043a \u043d\u0438\u0437\u043a\u043e\u0435, \u0430 \u0440\u044f\u0434 \u0440\u0430\u0431\u043e\u0442 \u043f\u0440\u044f\u043c\u043e \u0443\u043a\u0430\u0437\u044b\u0432\u0430\u0435\u0442 \u043d\u0430 \u043c\u0435\u0442\u043e\u0434\u043e\u043b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u0438\u0435 \u043f\u0440\u043e\u0431\u043b\u0435\u043c\u044b \u0438 \u0432\u043e\u043f\u0440\u043e\u0441\u044b \u043a \u043d\u0430\u0434\u0451\u0436\u043d\u043e\u0441\u0442\u0438. \u041d\u0435\u0442 \u0432\u043d\u044f\u0442\u043d\u044b\u0445 \u0434\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432, \u0447\u0442\u043e \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0430 \u0434\u0435\u043b\u0430\u0435\u0442 \u0432\u0430\u0441 \u043c\u0435\u043d\u0435\u0435 \u0438\u043c\u043f\u0443\u043b\u044c\u0441\u0438\u0432\u043d\u044b\u043c \u0438\u043b\u0438 \u043b\u0443\u0447\u0448\u0438\u043c \u0432 \u0440\u0435\u0448\u0435\u043d\u0438\u044f\u0445 \u0437\u0430 \u043f\u0440\u0435\u0434\u0435\u043b\u0430\u043c\u0438 \u0438\u0433\u0440\u044b, \u0442\u0430\u043a \u0447\u0442\u043e \u043a \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f\u043c \xab\u043f\u0440\u043e\u043a\u0430\u0447\u0430\u0439 \u0441\u0432\u043e\u0439 \u0440\u0438\u0441\u043a\xbb \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u0435\u0441\u044c \u0441\u043a\u0435\u043f\u0442\u0438\u0447\u0435\u0441\u043a\u0438.",rec:"\u0418\u0433\u0440\u0430\u0439\u0442\u0435, \u0447\u0442\u043e\u0431\u044b \u0437\u0430\u043c\u0435\u0442\u0438\u0442\u044c \u0441\u0432\u043e\u0439 \u0448\u0430\u0431\u043b\u043e\u043d \u2014 \u0437\u0430\u0431\u0438\u0440\u0430\u0435\u0442\u0435 \u0441\u043b\u0438\u0448\u043a\u043e\u043c \u0440\u0430\u043d\u043e \u0438\u043b\u0438 \u0441\u043b\u0438\u0448\u043a\u043e\u043c \u0447\u0430\u0441\u0442\u043e \u0434\u043e\u0432\u043e\u0434\u0438\u0442\u0435 \u0434\u043e \u0432\u0437\u0440\u044b\u0432\u0430? \u2014 \u0430 \u043d\u0435 \u043a\u0430\u043a \u0432 \u043b\u0435\u043a\u0430\u0440\u0441\u0442\u0432\u043e \u043e\u0442 \u0438\u043c\u043f\u0443\u043b\u044c\u0441\u0438\u0432\u043d\u043e\u0441\u0442\u0438.",faq:[["\u0415\u0441\u0442\u044c \u043b\u0438 \u043e\u043f\u0442\u0438\u043c\u0430\u043b\u044c\u043d\u043e\u0435 \u0447\u0438\u0441\u043b\u043e \u043d\u0430\u0436\u0430\u0442\u0438\u0439?","\u0413\u0440\u0443\u0431\u043e \u2014 \u0434\u0430: \u0432 \u0434\u043e\u043b\u0433\u0443\u044e \u0432\u044b\u0433\u043e\u0434\u043d\u0435\u0435 \u0437\u0430\u0431\u0438\u0440\u0430\u0442\u044c \u0447\u0443\u0442\u044c \u0440\u0430\u043d\u044c\u0448\u0435 \u0441\u0440\u0435\u0434\u043d\u0435\u0439 \u0442\u043e\u0447\u043a\u0438 \u0432\u0437\u0440\u044b\u0432\u0430, \u0432\u0435\u0434\u044c \u043a\u0430\u0436\u0434\u043e\u0435 \u043b\u0438\u0448\u043d\u0435\u0435 \u043d\u0430\u0436\u0430\u0442\u0438\u0435 \u0441\u0442\u043e\u0438\u0442 \u0432\u0441\u0451 \u043c\u0435\u043d\u044c\u0448\u0435 \u043f\u043e \u043c\u0435\u0440\u0435 \u0440\u043e\u0441\u0442\u0430 \u0440\u0438\u0441\u043a\u0430. \u041d\u043e \u0442\u043e\u0447\u043d\u0430\u044f \u0437\u043e\u043b\u043e\u0442\u0430\u044f \u0441\u0435\u0440\u0435\u0434\u0438\u043d\u0430 \u0441\u043a\u0440\u044b\u0442\u0430 \u0438 \u043f\u043b\u0430\u0432\u0430\u0435\u0442 \u043c\u0435\u0436\u0434\u0443 \u0442\u0438\u043f\u0430\u043c\u0438 \u0448\u0430\u0440\u043e\u0432 \u2014 \u0432 \u044d\u0442\u043e\u043c \u0432\u0435\u0441\u044c \u0441\u043c\u044b\u0441\u043b."],["\u0421\u0434\u0435\u043b\u0430\u0435\u0442 \u043b\u0438 \u044d\u0442\u043e \u043c\u0435\u043d\u044f \u043c\u0435\u043d\u0435\u0435 \u0438\u043c\u043f\u0443\u043b\u044c\u0441\u0438\u0432\u043d\u044b\u043c \u0432 \u0436\u0438\u0437\u043d\u0438?","\u0412\u043d\u044f\u0442\u043d\u044b\u0445 \u0434\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432 \u044d\u0442\u043e\u0433\u043e \u043d\u0435\u0442. \u0412\u043d\u0443\u0442\u0440\u0438 \u0438\u0433\u0440\u044b \u0432\u044b \u043d\u0430\u0443\u0447\u0438\u0442\u0435\u0441\u044c \u0442\u043e\u0447\u043d\u0435\u0435 \u043e\u0446\u0435\u043d\u0438\u0432\u0430\u0442\u044c \u0440\u0438\u0441\u043a, \u043d\u043e \u043f\u0435\u0440\u0435\u043d\u043e\u0441 \u043d\u0430 \u0440\u0435\u0430\u043b\u044c\u043d\u044b\u0435 \u0440\u0435\u0448\u0435\u043d\u0438\u044f \u043d\u0430\u0434\u0451\u0436\u043d\u043e \u043d\u0435 \u043f\u043e\u043a\u0430\u0437\u0430\u043d, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u043c\u044b \u0442\u0430\u043a\u043e\u0433\u043e \u043d\u0435 \u043e\u0431\u0435\u0449\u0430\u0435\u043c."],["\u041b\u043e\u043f\u043d\u0443\u0432\u0448\u0438\u0439 \u0448\u0430\u0440 \u2014 \u044d\u0442\u043e \u043e\u0448\u0438\u0431\u043a\u0430?","\u041d\u0435 \u043e\u0431\u044f\u0437\u0430\u0442\u0435\u043b\u044c\u043d\u043e. \u0415\u0441\u043b\u0438 \u0448\u0430\u0440\u044b \u0443 \u0432\u0430\u0441 \u043d\u0435 \u043b\u043e\u043f\u0430\u044e\u0442\u0441\u044f \u0432\u043e\u043e\u0431\u0449\u0435, \u0432\u044b \u043f\u043e\u0447\u0442\u0438 \u043d\u0430\u0432\u0435\u0440\u043d\u044f\u043a\u0430 \u0437\u0430\u0431\u0438\u0440\u0430\u0435\u0442\u0435 \u0441\u043b\u0438\u0448\u043a\u043e\u043c \u0440\u0430\u043d\u043e \u0438 \u043d\u0435\u0434\u043e\u0431\u0438\u0440\u0430\u0435\u0442\u0435 \u043e\u0447\u043a\u0438; \u0447\u0430\u0441\u0442\u044c \u0432\u0437\u0440\u044b\u0432\u043e\u0432 \u2014 \u044d\u0442\u043e \u043f\u043b\u0430\u0442\u0430 \u0437\u0430 \u0442\u043e, \u0447\u0442\u043e \u0432\u044b \u043a\u0430\u0447\u0430\u0435\u0442\u0435 \u0443 \u0440\u0430\u0437\u0443\u043c\u043d\u043e\u0433\u043e \u043f\u0440\u0435\u0434\u0435\u043b\u0430."]],variants:"\u0420\u0430\u0441\u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0451\u043d\u043d\u044b\u0435 \u0432\u0435\u0440\u0441\u0438\u0438 \u043c\u0435\u043d\u044f\u044e\u0442 \u0448\u0430\u043d\u0441 \u0432\u0437\u0440\u044b\u0432\u0430 \u043f\u043e \u0446\u0432\u0435\u0442\u0443 \u0448\u0430\u0440\u0430 (\u043e\u0434\u043d\u0438 \u0437\u0430\u043c\u0435\u0442\u043d\u043e \u043e\u043f\u0430\u0441\u043d\u0435\u0435 \u0434\u0440\u0443\u0433\u0438\u0445), \u0434\u043e\u0431\u0430\u0432\u043b\u044f\u044e\u0442 \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u0438\u0439 \u0440\u0435\u0436\u0438\u043c \u0441 \u0437\u0430\u0440\u0430\u043d\u0435\u0435 \u0437\u0430\u0434\u0430\u043d\u043d\u044b\u043c \u0447\u0438\u0441\u043b\u043e\u043c \u043d\u0430\u0436\u0430\u0442\u0438\u0439, \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u044e\u0442 \u043f\u043e\u0434\u0440\u043e\u0441\u0442\u043a\u043e\u0432\u044b\u0439 \u0432\u0430\u0440\u0438\u0430\u043d\u0442 (BART-Y) \u0438\u043b\u0438 \u0437\u0430\u043c\u0435\u043d\u044f\u044e\u0442 \u0434\u0435\u043d\u044c\u0433\u0438 \u043e\u0447\u043a\u0430\u043c\u0438. \u0414\u043b\u044f \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u0439 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044e\u0442 \u0438 VR-\u0432\u0435\u0440\u0441\u0438\u0438, \u0438 \u0430\u0434\u0430\u043f\u0442\u0430\u0446\u0438\u0438 \u043f\u043e\u0434 \u0441\u043a\u0430\u043d\u0435\u0440 \u043c\u043e\u0437\u0433\u0430."},en:{about:"BART: Risk Balloon is a decision-making game built on the Balloon Analogue Risk Task. You inflate a virtual balloon one pump at a time; each pump adds money to a temporary pot but also nudges up the chance the balloon bursts. You can bank the pot at any moment, or push your luck for more \u2014 if it pops first, you lose everything in that balloon.",benefit:"It trains risk calibration under uncertainty: weighing a growing reward against a rising chance of loss, and knowing when to stop. You also practise reward sensitivity and impulse control, since the smart move is to cash out before greed costs you the round.",history:"The task was created in academic psychology in the early 2000s as a behavioural alternative to risk questionnaires, where people often misreport how reckless they really are. It spread quickly through addiction, impulsivity and adolescence research, was adapted for youth (BART-Y), for automatic and neuroimaging versions, and eventually became a popular gamified exercise.",creator:"It was developed by Carl W. Lejuez and colleagues at the University of Maryland and first published in 2002 in the Journal of Experimental Psychology: Applied. Lejuez has said the idea came from watching people pump up balloons at a fair, noticing that some stop early while others keep going until it bursts.",methods:"Decide on a target number of pumps before each balloon and bank around it instead of reacting pump by pump. Track roughly how far balloons tend to go before popping and aim a little under that, and do not chase losses by inflating harder right after a burst \u2014 that is exactly when people overshoot.",duration:"Short sessions work best \u2014 about 20 to 40 balloons, five to ten minutes, is plenty. Treat it as an occasional decision-making warm-up a few times a week rather than something to grind daily.",research:"Evidence is strongest for what you would expect: the task reliably measures risk-taking in the lab, has acceptable test-retest reliability, and people's pumping correlates modestly with some real-world behaviours like smoking, drug use and gambling. But the link to actual life decisions is weak and inconsistent, agreement with self-report risk measures is poor, and several papers flag methodological and reliability problems. There is no good evidence that practising it makes you less impulsive or a better decision-maker outside the game, so treat any 'train your risk-taking' promise with caution.",rec:"Play it to notice your own pattern \u2014 do you cash out too early or pop too often? \u2014 not as a cure for impulsivity.",faq:[["Is there an optimal number of pumps?","Roughly, yes: the long-run best strategy is to bank a bit before the average bursting point, since each extra pump is worth less as the risk climbs. But the exact sweet spot is hidden and shifts between balloon types, which is the whole point."],["Will this make me less impulsive in real life?","There is no solid evidence for that. You will get better at judging risk inside this game, but transfer to real-world decisions has not been reliably shown, so we do not promise it."],["Is losing a balloon a mistake?","Not necessarily. If you never pop a balloon you are almost certainly cashing out too early and leaving points on the table; some bursts are the price of pumping near the smart limit."]],variants:"Common versions change the colour-coded burst odds (some balloons are far riskier than others), add an automatic mode where you pre-set the number of pumps, use a youth-friendly version (BART-Y), or replace money with points. Virtual-reality and brain-imaging adaptations also exist for research."},es:{about:"BART: Globo del Riesgo es un juego de toma de decisiones basado en la Balloon Analogue Risk Task. Inflas un globo virtual bombeo a bombeo; cada bombeo a\xf1ade dinero a un bote temporal, pero tambi\xe9n eleva un poco la probabilidad de que el globo reviente. Puedes guardar el bote en cualquier momento o tentar a la suerte para conseguir m\xe1s; si revienta antes, pierdes todo lo de ese globo.",benefit:"Entrena la calibraci\xf3n del riesgo bajo incertidumbre: sopesar una recompensa creciente frente a una probabilidad de p\xe9rdida que sube, y saber cu\xe1ndo parar. Tambi\xe9n practicas la sensibilidad a la recompensa y el control de impulsos, ya que la jugada inteligente es retirarte antes de que la codicia te cueste la ronda.",history:"La tarea se cre\xf3 en la psicolog\xeda acad\xe9mica a comienzos de los a\xf1os 2000 como alternativa conductual a los cuestionarios de riesgo, en los que la gente suele informar mal de lo imprudente que es en realidad. Se extendi\xf3 r\xe1pidamente por la investigaci\xf3n sobre adicciones, impulsividad y adolescencia, se adapt\xf3 para j\xf3venes (BART-Y), a versiones autom\xe1ticas y de neuroimagen, y acab\xf3 convirti\xe9ndose en un popular ejercicio gamificado.",creator:"La desarrollaron Carl W. Lejuez y colaboradores en la Universidad de Maryland y se public\xf3 por primera vez en 2002 en el Journal of Experimental Psychology: Applied. Lejuez ha contado que la idea surgi\xf3 al ver a la gente inflar globos en una feria, al notar que algunos paran pronto mientras otros siguen hasta que revienta.",methods:"Decide un n\xfamero objetivo de bombeos antes de cada globo y guarda el bote en torno a esa cifra en lugar de reaccionar bombeo a bombeo. Lleva la cuenta, a grandes rasgos, de hasta d\xf3nde suelen llegar los globos antes de reventar y apunta un poco por debajo de eso, y no persigas las p\xe9rdidas inflando con m\xe1s fuerza justo despu\xe9s de un revent\xf3n: ah\xed es exactamente cuando la gente se pasa.",duration:"Las sesiones cortas funcionan mejor: unos 20 a 40 globos, de cinco a diez minutos, es m\xe1s que suficiente. T\xf3malo como un calentamiento ocasional de toma de decisiones unas cuantas veces por semana, en lugar de algo que machacar a diario.",research:"La evidencia es m\xe1s s\xf3lida para lo esperable: la tarea mide de forma fiable la asunci\xf3n de riesgos en el laboratorio, tiene una fiabilidad test-retest aceptable, y el ritmo de bombeo de cada persona correlaciona de forma modesta con algunos comportamientos del mundo real, como fumar, el consumo de drogas y el juego. Pero el v\xednculo con las decisiones reales de la vida es d\xe9bil e inconstante, la concordancia con las medidas de riesgo autoinformadas es pobre, y varios art\xedculos se\xf1alan problemas metodol\xf3gicos y de fiabilidad. No hay buena evidencia de que practicarla te vuelva menos impulsivo ni un mejor tomador de decisiones fuera del juego, as\xed que toma con cautela cualquier promesa de \"entrena tu asunci\xf3n de riesgos\".",rec:"Ju\xe9galo para reconocer tu propio patr\xf3n (\xbfte retiras demasiado pronto o revientas demasiadas veces?), no como una cura para la impulsividad.",faq:[["\xbfExiste un n\xfamero \xf3ptimo de bombeos?","A grandes rasgos, s\xed: la mejor estrategia a largo plazo es guardar el bote un poco antes del punto medio de revent\xf3n, ya que cada bombeo extra vale menos a medida que sube el riesgo. Pero el punto exacto est\xe1 oculto y cambia entre tipos de globo, que es justamente el objetivo."],["\xbfEsto me har\xe1 menos impulsivo en la vida real?","No hay evidencia s\xf3lida de ello. Mejorar\xe1s a la hora de juzgar el riesgo dentro de este juego, pero no se ha demostrado de forma fiable la transferencia a las decisiones del mundo real, as\xed que no lo prometemos."],["\xbfPerder un globo es un error?","No necesariamente. Si nunca revientas un globo, es casi seguro que te est\xe1s retirando demasiado pronto y dejando puntos sobre la mesa; algunos reventones son el precio de bombear cerca del l\xedmite inteligente."]],variants:"Las versiones habituales cambian las probabilidades de revent\xf3n codificadas por colores (algunos globos son mucho m\xe1s arriesgados que otros), a\xf1aden un modo autom\xe1tico en el que prefijas el n\xfamero de bombeos, usan una versi\xf3n para j\xf3venes (BART-Y) o sustituyen el dinero por puntos. Tambi\xe9n existen adaptaciones de realidad virtual y de neuroimagen para la investigaci\xf3n."},de:{about:"BART: Risk Balloon ist ein Entscheidungsspiel, das auf dem Balloon Analogue Risk Task aufbaut. Du pumpst einen virtuellen Ballon Sto\xdf f\xfcr Sto\xdf auf; jeder Sto\xdf legt Geld in einen vorl\xe4ufigen Topf, schiebt aber zugleich die Wahrscheinlichkeit nach oben, dass der Ballon platzt. Du kannst den Topf jederzeit sichern oder dein Gl\xfcck f\xfcr mehr herausfordern \u2013 platzt er vorher, verlierst du alles in diesem Ballon.",benefit:"Trainiert wird das Abw\xe4gen von Risiko unter Unsicherheit: eine wachsende Belohnung gegen eine steigende Verlustwahrscheinlichkeit abzuw\xe4gen und zu wissen, wann man aufh\xf6rt. Du \xfcbst au\xdferdem Belohnungssensitivit\xe4t und Impulskontrolle, denn der kluge Zug ist, auszuzahlen, bevor die Gier dich die Runde kostet.",history:"Die Aufgabe entstand Anfang der 2000er-Jahre in der akademischen Psychologie als verhaltensbasierte Alternative zu Risiko-Frageb\xf6gen, bei denen Menschen oft falsch angeben, wie waghalsig sie wirklich sind. Sie verbreitete sich rasch in der Sucht-, Impulsivit\xe4ts- und Jugendforschung, wurde f\xfcr Jugendliche angepasst (BART-Y), f\xfcr automatische und bildgebende Versionen, und wurde schlie\xdflich zu einer beliebten spielerischen \xdcbung.",creator:"Sie wurde von Carl W. Lejuez und Kollegen an der University of Maryland entwickelt und 2002 erstmals im Journal of Experimental Psychology: Applied ver\xf6ffentlicht. Lejuez hat erz\xe4hlt, die Idee sei beim Beobachten von Menschen entstanden, die auf einem Jahrmarkt Ballons aufpumpten \u2013 ihm fiel auf, dass manche fr\xfch aufh\xf6ren, w\xe4hrend andere weitermachen, bis er platzt.",methods:"Lege vor jedem Ballon eine Zielzahl an St\xf6\xdfen fest und sichere dich rund um sie ab, statt Sto\xdf f\xfcr Sto\xdf zu reagieren. Behalte grob im Blick, wie weit Ballons in der Regel kommen, bevor sie platzen, und ziele ein wenig darunter, und jage Verlusten nicht hinterher, indem du direkt nach einem Platzer st\xe4rker pumpst \u2013 genau dann schie\xdfen Menschen \xfcbers Ziel hinaus.",duration:"Kurze Sitzungen funktionieren am besten \u2013 etwa 20 bis 40 Ballons, f\xfcnf bis zehn Minuten, reichen v\xf6llig. Behandle es als gelegentliches Entscheidungs-Aufw\xe4rmen ein paar Mal die Woche statt als etwas, das man t\xe4glich durchackert.",research:"Am st\xe4rksten belegt ist das Erwartbare: Die Aufgabe misst das Risikoverhalten im Labor zuverl\xe4ssig, hat eine akzeptable Retest-Reliabilit\xe4t, und das Pumpverhalten der Leute korreliert m\xe4\xdfig mit einigen realen Verhaltensweisen wie Rauchen, Drogenkonsum und Gl\xfccksspiel. Doch der Bezug zu tats\xe4chlichen Lebensentscheidungen ist schwach und uneinheitlich, die \xdcbereinstimmung mit selbstberichteten Risikoma\xdfen ist gering, und mehrere Arbeiten weisen auf methodische und Reliabilit\xe4tsprobleme hin. Es gibt keine guten Belege daf\xfcr, dass ihr \xdcben dich au\xdferhalb des Spiels weniger impulsiv oder zu einem besseren Entscheider macht, behandle also jedes Versprechen, dein Risikoverhalten zu trainieren, mit Vorsicht.",rec:"Spiele es, um dein eigenes Muster zu erkennen \u2013 zahlst du zu fr\xfch aus oder l\xe4sst du zu oft platzen? \u2013, nicht als Heilmittel gegen Impulsivit\xe4t.",faq:[["Gibt es eine optimale Zahl an St\xf6\xdfen?","Grob gesagt ja: Die langfristig beste Strategie ist, ein wenig vor dem durchschnittlichen Platzpunkt zu sichern, da jeder weitere Sto\xdf weniger wert ist, je mehr das Risiko steigt. Doch der genaue Sweetspot ist verborgen und verschiebt sich zwischen den Ballontypen, und genau das ist der Sinn der Sache."],["Werde ich dadurch im echten Leben weniger impulsiv?","Daf\xfcr gibt es keine soliden Belege. Du wirst besser darin, das Risiko innerhalb dieses Spiels einzusch\xe4tzen, aber eine \xdcbertragung auf reale Entscheidungen ist nicht verl\xe4sslich gezeigt, also versprechen wir sie nicht."],["Ist es ein Fehler, einen Ballon zu verlieren?","Nicht unbedingt. Wenn du nie einen Ballon platzen l\xe4sst, zahlst du mit ziemlicher Sicherheit zu fr\xfch aus und l\xe4sst Punkte liegen; manche Platzer sind der Preis daf\xfcr, nahe an der klugen Grenze zu pumpen."]],variants:"G\xe4ngige Versionen \xe4ndern die farbcodierten Platzwahrscheinlichkeiten (manche Ballons sind weit riskanter als andere), f\xfcgen einen automatischen Modus hinzu, in dem du die Zahl der St\xf6\xdfe vorab festlegst, nutzen eine jugendgerechte Version (BART-Y) oder ersetzen Geld durch Punkte. F\xfcr die Forschung gibt es zudem Anpassungen in der virtuellen Realit\xe4t und mit Bildgebung."},pt:{about:"BART: Bal\xe3o de Risco \xe9 um jogo de tomada de decis\xe3o baseado na Balloon Analogue Risk Task. Voc\xea infla um bal\xe3o virtual uma bombada de cada vez; cada bombada acrescenta dinheiro a um pote tempor\xe1rio, mas tamb\xe9m eleva um pouco a chance de o bal\xe3o estourar. Voc\xea pode guardar o pote a qualquer momento ou for\xe7ar a sorte por mais \u2014 se ele estourar antes, voc\xea perde tudo o que havia naquele bal\xe3o.",benefit:"Treina a calibra\xe7\xe3o do risco sob incerteza: pesar uma recompensa crescente contra uma chance crescente de perda, e saber a hora de parar. Voc\xea tamb\xe9m pratica a sensibilidade \xe0 recompensa e o controle de impulsos, j\xe1 que a jogada inteligente \xe9 encaixar o ganho antes que a gan\xe2ncia te custe a rodada.",history:"A tarefa foi criada na psicologia acad\xeamica no in\xedcio dos anos 2000 como uma alternativa comportamental aos question\xe1rios de risco, em que as pessoas muitas vezes relatam mal o qu\xe3o imprudentes realmente s\xe3o. Espalhou-se rapidamente pela pesquisa sobre depend\xeancia, impulsividade e adolesc\xeancia, foi adaptada para jovens (BART-Y), para vers\xf5es autom\xe1ticas e de neuroimagem, e acabou virando um exerc\xedcio gamificado popular.",creator:"Foi desenvolvida por Carl W. Lejuez e colegas na Universidade de Maryland e publicada pela primeira vez em 2002 no Journal of Experimental Psychology: Applied. Lejuez contou que a ideia veio de observar pessoas enchendo bal\xf5es numa feira, notando que algumas paravam cedo enquanto outras seguiam at\xe9 estourar.",methods:"Decida um n\xfamero-alvo de bombadas antes de cada bal\xe3o e encaixe o ganho em torno dele, em vez de reagir bombada a bombada. Acompanhe mais ou menos at\xe9 onde os bal\xf5es costumam ir antes de estourar e mire um pouco abaixo disso, e n\xe3o persiga as perdas inflando com mais for\xe7a logo depois de um estouro \u2014 \xe9 exatamente a\xed que as pessoas exageram.",duration:"Sess\xf5es curtas funcionam melhor \u2014 cerca de 20 a 40 bal\xf5es, cinco a dez minutos, j\xe1 basta. Encare como um aquecimento ocasional de tomada de decis\xe3o algumas vezes por semana, n\xe3o como algo para insistir todo dia.",research:"A evid\xeancia \xe9 mais forte para o que se espera: a tarefa mede de forma confi\xe1vel a tomada de risco em laborat\xf3rio, tem confiabilidade teste-reteste aceit\xe1vel, e o n\xedvel de bombadas das pessoas se correlaciona de forma modesta com alguns comportamentos do mundo real, como fumar, uso de drogas e jogo. Mas o v\xednculo com as decis\xf5es reais da vida \xe9 fraco e inconsistente, a concord\xe2ncia com as medidas de risco autorrelatadas \xe9 ruim, e v\xe1rios artigos apontam problemas metodol\xf3gicos e de confiabilidade. N\xe3o h\xe1 boa evid\xeancia de que pratic\xe1-la te deixe menos impulsivo ou melhor em decis\xf5es fora do jogo, ent\xe3o encare com cautela qualquer promessa de \"treinar a sua tomada de risco\".",rec:"Jogue para perceber o seu pr\xf3prio padr\xe3o \u2014 voc\xea encaixa o ganho cedo demais ou estoura com muita frequ\xeancia? \u2014 e n\xe3o como cura para a impulsividade.",faq:[["Existe um n\xfamero ideal de bombadas?","Mais ou menos, sim: a melhor estrat\xe9gia a longo prazo \xe9 guardar o ganho um pouco antes do ponto m\xe9dio de estouro, j\xe1 que cada bombada extra vale menos \xe0 medida que o risco sobe. Mas o ponto exato \xe9 oculto e muda entre os tipos de bal\xe3o, e \xe9 justamente esse o ponto."],["Isso vai me deixar menos impulsivo na vida real?","N\xe3o h\xe1 evid\xeancia s\xf3lida disso. Voc\xea vai melhorar em avaliar o risco dentro deste jogo, mas a transfer\xeancia para decis\xf5es do mundo real n\xe3o foi demonstrada de forma confi\xe1vel, ent\xe3o n\xe3o prometemos isso."],["Perder um bal\xe3o \xe9 um erro?","N\xe3o necessariamente. Se voc\xea nunca estoura um bal\xe3o, est\xe1 quase com certeza encaixando o ganho cedo demais e deixando pontos na mesa; alguns estouros s\xe3o o pre\xe7o de bombar perto do limite inteligente."]],variants:"As vers\xf5es comuns mudam as chances de estouro codificadas por cor (alguns bal\xf5es s\xe3o bem mais arriscados do que outros), acrescentam um modo autom\xe1tico em que voc\xea predefine o n\xfamero de bombadas, usam uma vers\xe3o amig\xe1vel para jovens (BART-Y) ou substituem o dinheiro por pontos. Tamb\xe9m existem adapta\xe7\xf5es em realidade virtual e em neuroimagem para a pesquisa."},hi:{about:"BART: Risk Balloon \u090f\u0915 \u0928\u093f\u0930\u094d\u0923\u092f \u0932\u0947\u0928\u0947 \u0935\u093e\u0932\u093e \u0916\u0947\u0932 \u0939\u0948, \u091c\u094b Balloon Analogue Risk Task \u092a\u0930 \u0906\u0927\u093e\u0930\u093f\u0924 \u0939\u0948\u0964 \u0906\u092a \u090f\u0915 \u0906\u092d\u093e\u0938\u0940 \u0917\u0941\u092c\u094d\u092c\u093e\u0930\u0947 \u0915\u094b \u090f\u0915-\u090f\u0915 \u092a\u0902\u092a \u0915\u0930\u0915\u0947 \u092b\u0941\u0932\u093e\u0924\u0947 \u0939\u0948\u0902; \u0939\u0930 \u092a\u0902\u092a \u090f\u0915 \u0905\u0938\u094d\u0925\u093e\u092f\u0940 \u092a\u094b\u091f \u092e\u0947\u0902 \u092a\u0948\u0938\u0947 \u091c\u094b\u0921\u093c\u0924\u093e \u0939\u0948, \u092a\u0930 \u0938\u093e\u0925 \u0939\u0940 \u0917\u0941\u092c\u094d\u092c\u093e\u0930\u0947 \u0915\u0947 \u092b\u091f\u0928\u0947 \u0915\u0940 \u0938\u0902\u092d\u093e\u0935\u0928\u093e \u092d\u0940 \u0925\u094b\u0921\u093c\u0940-\u0925\u094b\u0921\u093c\u0940 \u092c\u0922\u093c\u093e\u0924\u093e \u091c\u093e\u0924\u093e \u0939\u0948\u0964 \u0906\u092a \u0915\u093f\u0938\u0940 \u092d\u0940 \u092a\u0932 \u092a\u094b\u091f \u0915\u094b \u092c\u0948\u0902\u0915 \u092e\u0947\u0902 \u091c\u092e\u093e \u0915\u0930 \u0938\u0915\u0924\u0947 \u0939\u0948\u0902, \u092f\u093e \u0914\u0930 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0915\u0947 \u0932\u093e\u0932\u091a \u092e\u0947\u0902 \u0926\u093e\u0901\u0935 \u092c\u0922\u093c\u093e \u0938\u0915\u0924\u0947 \u0939\u0948\u0902 \u2014 \u092a\u0930 \u0905\u0917\u0930 \u0935\u0939 \u092a\u0939\u0932\u0947 \u092b\u091f \u0917\u092f\u093e, \u0924\u094b \u0909\u0938 \u0917\u0941\u092c\u094d\u092c\u093e\u0930\u0947 \u0915\u093e \u0938\u093e\u0930\u093e \u092a\u0948\u0938\u093e \u0921\u0942\u092c \u091c\u093e\u0924\u093e \u0939\u0948\u0964",benefit:"\u092f\u0939 \u0905\u0928\u093f\u0936\u094d\u091a\u093f\u0924\u0924\u093e \u092e\u0947\u0902 \u091c\u094b\u0916\u093f\u092e \u0924\u094c\u0932\u0928\u0947 \u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0930\u093e\u0924\u093e \u0939\u0948: \u092c\u0922\u093c\u0924\u0947 \u0907\u0928\u093e\u092e \u0915\u094b \u0928\u0941\u0915\u093c\u0938\u093e\u0928 \u0915\u0940 \u092c\u0922\u093c\u0924\u0940 \u0938\u0902\u092d\u093e\u0935\u0928\u093e \u0915\u0947 \u092e\u0941\u0915\u093c\u093e\u092c\u0932\u0947 \u0924\u094c\u0932\u0928\u093e, \u0914\u0930 \u092f\u0939 \u091c\u093e\u0928\u0928\u093e \u0915\u093f \u0915\u092c \u0930\u0941\u0915 \u091c\u093e\u0928\u093e \u0939\u0948\u0964 \u0938\u093e\u0925 \u0939\u0940 \u0906\u092a \u0907\u0928\u093e\u092e \u0915\u0947 \u092a\u094d\u0930\u0924\u093f \u0938\u0902\u0935\u0947\u0926\u0928\u0936\u0940\u0932\u0924\u093e \u0914\u0930 \u0906\u0935\u0947\u0917-\u0928\u093f\u092f\u0902\u0924\u094d\u0930\u0923 \u092d\u0940 \u0938\u093e\u0927\u0924\u0947 \u0939\u0948\u0902, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u0938\u092e\u091d\u0926\u093e\u0930\u0940 \u0907\u0938\u0940 \u092e\u0947\u0902 \u0939\u0948 \u0915\u093f \u0932\u093e\u0932\u091a \u0930\u093e\u0909\u0902\u0921 \u092c\u093f\u0917\u093e\u0921\u093c \u0926\u0947, \u0909\u0938\u0938\u0947 \u092a\u0939\u0932\u0947 \u0939\u0940 \u092a\u0948\u0938\u093e \u092d\u0941\u0928\u093e \u0932\u0947\u0902\u0964",history:"\u092f\u0939 \u091f\u093e\u0938\u094d\u0915 2000 \u0915\u0947 \u0926\u0936\u0915 \u0915\u0940 \u0936\u0941\u0930\u0941\u0906\u0924 \u092e\u0947\u0902 \u0905\u0915\u093e\u0926\u092e\u093f\u0915 \u092e\u0928\u094b\u0935\u093f\u091c\u094d\u091e\u093e\u0928 \u092e\u0947\u0902 \u092c\u0928\u093e \u2014 \u091c\u094b\u0916\u093f\u092e \u092e\u093e\u092a\u0928\u0947 \u0935\u093e\u0932\u0940 \u092a\u094d\u0930\u0936\u094d\u0928\u093e\u0935\u0932\u093f\u092f\u094b\u0902 \u0915\u0947 \u090f\u0915 \u0935\u094d\u092f\u0935\u0939\u093e\u0930-\u0906\u0927\u093e\u0930\u093f\u0924 \u0935\u093f\u0915\u0932\u094d\u092a \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u092a\u094d\u0930\u0936\u094d\u0928\u093e\u0935\u0932\u093f\u092f\u094b\u0902 \u092e\u0947\u0902 \u0932\u094b\u0917 \u0905\u0915\u094d\u0938\u0930 \u0917\u093c\u0932\u0924 \u092c\u0924\u093e\u0924\u0947 \u0939\u0948\u0902 \u0915\u093f \u0935\u0947 \u0905\u0938\u0932 \u092e\u0947\u0902 \u0915\u093f\u0924\u0928\u0947 \u0932\u093e\u092a\u0930\u0935\u093e\u0939 \u0939\u0948\u0902\u0964 \u092f\u0939 \u091c\u0932\u094d\u0926\u0940 \u0939\u0940 \u0932\u0924, \u0906\u0935\u0947\u0917 \u0914\u0930 \u0915\u093f\u0936\u094b\u0930\u093e\u0935\u0938\u094d\u0925\u093e \u0915\u0947 \u0936\u094b\u0927 \u092e\u0947\u0902 \u092b\u0948\u0932 \u0917\u092f\u093e, \u092f\u0941\u0935\u093e\u0913\u0902 \u0915\u0947 \u0932\u093f\u090f \u0922\u093e\u0932\u093e \u0917\u092f\u093e (BART-Y), \u0938\u094d\u0935\u091a\u093e\u0932\u093f\u0924 \u0914\u0930 \u0928\u094d\u092f\u0942\u0930\u094b\u0907\u092e\u0947\u091c\u093f\u0902\u0917 \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u092c\u0928\u0947, \u0914\u0930 \u0906\u0916\u093c\u093f\u0930\u0915\u093e\u0930 \u092f\u0939 \u090f\u0915 \u0932\u094b\u0915\u092a\u094d\u0930\u093f\u092f \u0917\u0947\u092e\u093f\u092b\u093c\u093e\u0907\u0921 \u0905\u092d\u094d\u092f\u093e\u0938 \u092c\u0928 \u0917\u092f\u093e\u0964",creator:"\u0907\u0938\u0947 University of Maryland \u092e\u0947\u0902 Carl W. Lejuez \u0914\u0930 \u0909\u0928\u0915\u0947 \u0938\u093e\u0925\u093f\u092f\u094b\u0902 \u0928\u0947 \u0935\u093f\u0915\u0938\u093f\u0924 \u0915\u093f\u092f\u093e \u0914\u0930 \u092a\u0939\u0932\u0940 \u092c\u093e\u0930 2002 \u092e\u0947\u0902 Journal of Experimental Psychology: Applied \u092e\u0947\u0902 \u092a\u094d\u0930\u0915\u093e\u0936\u093f\u0924 \u0915\u093f\u092f\u093e\u0964 Lejuez \u0928\u0947 \u092c\u0924\u093e\u092f\u093e \u0939\u0948 \u0915\u093f \u092f\u0939 \u0935\u093f\u091a\u093e\u0930 \u0909\u0928\u094d\u0939\u0947\u0902 \u092e\u0947\u0932\u0947 \u092e\u0947\u0902 \u0932\u094b\u0917\u094b\u0902 \u0915\u094b \u0917\u0941\u092c\u094d\u092c\u093e\u0930\u0947 \u092b\u0941\u0932\u093e\u0924\u0947 \u0926\u0947\u0916\u0915\u0930 \u0938\u0942\u091d\u093e \u2014 \u0909\u0928\u094d\u0939\u094b\u0902\u0928\u0947 \u0917\u093c\u094c\u0930 \u0915\u093f\u092f\u093e \u0915\u093f \u0915\u0941\u091b \u0932\u094b\u0917 \u091c\u0932\u094d\u0926\u0940 \u0930\u0941\u0915 \u091c\u093e\u0924\u0947 \u0939\u0948\u0902, \u091c\u092c\u0915\u093f \u0915\u0941\u091b \u0924\u092c \u0924\u0915 \u092b\u0941\u0932\u093e\u0924\u0947 \u0930\u0939\u0924\u0947 \u0939\u0948\u0902 \u091c\u092c \u0924\u0915 \u0917\u0941\u092c\u094d\u092c\u093e\u0930\u093e \u092b\u091f \u0928 \u091c\u093e\u090f\u0964",methods:"\u0939\u0930 \u0917\u0941\u092c\u094d\u092c\u093e\u0930\u0947 \u0938\u0947 \u092a\u0939\u0932\u0947 \u092a\u0902\u092a\u094b\u0902 \u0915\u0940 \u090f\u0915 \u0924\u092f \u0938\u0902\u0916\u094d\u092f\u093e \u092e\u0928 \u092e\u0947\u0902 \u092c\u0928\u093e \u0932\u0947\u0902 \u0914\u0930 \u092a\u0902\u092a-\u0926\u0930-\u092a\u0902\u092a \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0926\u0947\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u0909\u0938\u0940 \u0915\u0947 \u0906\u0938\u092a\u093e\u0938 \u092a\u0948\u0938\u093e \u091c\u092e\u093e \u0915\u0930 \u0932\u0947\u0902\u0964 \u092e\u094b\u091f\u0947 \u0924\u094c\u0930 \u092a\u0930 \u0907\u0938 \u092c\u093e\u0924 \u092a\u0930 \u0928\u091c\u093c\u0930 \u0930\u0916\u0947\u0902 \u0915\u093f \u0917\u0941\u092c\u094d\u092c\u093e\u0930\u0947 \u0906\u092e\u0924\u094c\u0930 \u092a\u0930 \u092b\u091f\u0928\u0947 \u0938\u0947 \u092a\u0939\u0932\u0947 \u0915\u093f\u0924\u0928\u0940 \u0926\u0942\u0930 \u0924\u0915 \u091c\u093e\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u0909\u0938\u0938\u0947 \u0925\u094b\u0921\u093c\u093e \u0915\u092e \u092a\u0930 \u0930\u0941\u0915\u0928\u0947 \u0915\u093e \u0932\u0915\u094d\u0937\u094d\u092f \u0930\u0916\u0947\u0902; \u0914\u0930 \u0915\u093f\u0938\u0940 \u0917\u0941\u092c\u094d\u092c\u093e\u0930\u0947 \u0915\u0947 \u092b\u091f\u0928\u0947 \u0915\u0947 \u0924\u0941\u0930\u0902\u0924 \u092c\u093e\u0926 \u0928\u0941\u0915\u093c\u0938\u093e\u0928 \u0915\u0940 \u092d\u0930\u092a\u093e\u0908 \u0915\u0947 \u0932\u093f\u090f \u0914\u0930 \u091c\u093c\u094b\u0930 \u0938\u0947 \u092b\u0941\u0932\u093e\u0928\u0947 \u0928 \u0932\u0917\u0947\u0902 \u2014 \u0920\u0940\u0915 \u092f\u0939\u0940\u0902 \u0932\u094b\u0917 \u0939\u0926 \u092a\u093e\u0930 \u0915\u0930 \u091c\u093e\u0924\u0947 \u0939\u0948\u0902\u0964",duration:"\u091b\u094b\u091f\u0947 \u0938\u0924\u094d\u0930 \u0938\u092c\u0938\u0947 \u0905\u091a\u094d\u091b\u0947 \u0930\u0939\u0924\u0947 \u0939\u0948\u0902 \u2014 \u0915\u093c\u0930\u0940\u092c 20 \u0938\u0947 40 \u0917\u0941\u092c\u094d\u092c\u093e\u0930\u0947, \u092a\u093e\u0901\u091a \u0938\u0947 \u0926\u0938 \u092e\u093f\u0928\u091f, \u0915\u093e\u092b\u093c\u0940 \u0939\u0948\u0902\u0964 \u0907\u0938\u0947 \u0930\u094b\u091c\u093c \u0930\u0917\u0921\u093c\u0928\u0947 \u0935\u093e\u0932\u0940 \u091a\u0940\u091c\u093c \u0915\u0947 \u092c\u091c\u093e\u092f \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u0915\u0941\u091b \u092c\u093e\u0930 \u0915\u093f\u092f\u093e \u091c\u093e\u0928\u0947 \u0935\u093e\u0932\u093e \u0928\u093f\u0930\u094d\u0923\u092f-\u0935\u093e\u0930\u094d\u092e-\u0905\u092a \u0938\u092e\u091d\u0947\u0902\u0964",research:"\u0938\u092c\u0938\u0947 \u092a\u0941\u0916\u093c\u094d\u0924\u093e \u0938\u092c\u0942\u0924 \u0935\u0939\u0940 \u0939\u0948\u0902 \u091c\u093f\u0928\u0915\u0940 \u0909\u092e\u094d\u092e\u0940\u0926 \u0939\u094b\u0917\u0940: \u092f\u0939 \u091f\u093e\u0938\u094d\u0915 \u092a\u094d\u0930\u092f\u094b\u0917\u0936\u093e\u0932\u093e \u092e\u0947\u0902 \u091c\u094b\u0916\u093f\u092e-\u0935\u094d\u092f\u0935\u0939\u093e\u0930 \u0915\u094b \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0922\u0902\u0917 \u0938\u0947 \u092e\u093e\u092a\u0924\u093e \u0939\u0948, \u0907\u0938\u0915\u0940 test-retest \u0935\u093f\u0936\u094d\u0935\u0938\u0928\u0940\u092f\u0924\u093e \u0920\u0940\u0915-\u0920\u093e\u0915 \u0939\u0948, \u0914\u0930 \u0932\u094b\u0917\u094b\u0902 \u0915\u0947 \u092a\u0902\u092a \u0915\u0930\u0928\u0947 \u0915\u093e \u0924\u0930\u0940\u0915\u093c\u093e \u0927\u0942\u092e\u094d\u0930\u092a\u093e\u0928, \u0928\u0936\u0947 \u0914\u0930 \u091c\u0941\u090f \u091c\u0948\u0938\u0947 \u0915\u0941\u091b \u0905\u0938\u0932 \u0935\u094d\u092f\u0935\u0939\u093e\u0930\u094b\u0902 \u0938\u0947 \u0939\u0932\u094d\u0915\u093e-\u0938\u093e \u092e\u0947\u0932 \u0916\u093e\u0924\u093e \u0939\u0948\u0964 \u092a\u0930 \u0905\u0938\u0932 \u091c\u093c\u093f\u0902\u0926\u0917\u0940 \u0915\u0947 \u092b\u093c\u0948\u0938\u0932\u094b\u0902 \u0938\u0947 \u0907\u0938\u0915\u093e \u091c\u0941\u0921\u093c\u093e\u0935 \u0915\u092e\u091c\u093c\u094b\u0930 \u0914\u0930 \u0917\u0921\u093c\u092c\u0921\u093c \u0939\u0948, \u0938\u094d\u0935-\u0930\u093f\u092a\u094b\u0930\u094d\u091f \u0935\u093e\u0932\u0947 \u091c\u094b\u0916\u093f\u092e-\u092e\u093e\u092a\u094b\u0902 \u0938\u0947 \u0907\u0938\u0915\u093e \u0924\u093e\u0932\u092e\u0947\u0932 \u0916\u093c\u0930\u093e\u092c \u0939\u0948, \u0914\u0930 \u0915\u0908 \u0936\u094b\u0927\u092a\u0924\u094d\u0930 \u0907\u0938\u0915\u0940 \u092a\u0926\u094d\u0927\u0924\u093f \u0914\u0930 \u0935\u093f\u0936\u094d\u0935\u0938\u0928\u0940\u092f\u0924\u093e \u0915\u0940 \u0926\u093f\u0915\u093c\u094d\u0915\u093c\u0924\u0947\u0902 \u0917\u093f\u0928\u093e\u0924\u0947 \u0939\u0948\u0902\u0964 \u0907\u0938 \u092c\u093e\u0924 \u0915\u093e \u0915\u094b\u0908 \u0905\u091a\u094d\u091b\u093e \u0938\u092c\u0942\u0924 \u0928\u0939\u0940\u0902 \u0915\u093f \u0907\u0938\u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0906\u092a\u0915\u094b \u0916\u0947\u0932 \u0915\u0947 \u092c\u093e\u0939\u0930 \u0915\u092e \u0906\u0935\u0947\u0917\u0940 \u092f\u093e \u092c\u0947\u0939\u0924\u0930 \u0928\u093f\u0930\u094d\u0923\u092f \u0932\u0947\u0928\u0947 \u0935\u093e\u0932\u093e \u092c\u0928\u093e \u0926\u0947\u0924\u093e \u0939\u0948, \u0907\u0938\u0932\u093f\u090f '\u0905\u092a\u0928\u0940 \u091c\u094b\u0916\u093f\u092e-\u092a\u094d\u0930\u0935\u0943\u0924\u094d\u0924\u093f \u0938\u093e\u0927 \u0932\u094b' \u091c\u0948\u0938\u0947 \u0915\u093f\u0938\u0940 \u092d\u0940 \u0935\u093e\u0926\u0947 \u0915\u094b \u0938\u093e\u0935\u0927\u093e\u0928\u0940 \u0938\u0947 \u0932\u0947\u0902\u0964",rec:"\u0907\u0938\u0947 \u0905\u092a\u0928\u0940 \u0916\u093c\u0941\u0926 \u0915\u0940 \u0906\u0926\u0924 \u092a\u0939\u091a\u093e\u0928\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0916\u0947\u0932\u0947\u0902 \u2014 \u0915\u094d\u092f\u093e \u0906\u092a \u0939\u0926 \u0938\u0947 \u091c\u0932\u094d\u0926\u0940 \u092a\u0948\u0938\u093e \u092d\u0941\u0928\u093e \u0932\u0947\u0924\u0947 \u0939\u0948\u0902, \u092f\u093e \u091c\u093c\u0930\u0942\u0930\u0924 \u0938\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u092c\u093e\u0930 \u0917\u0941\u092c\u094d\u092c\u093e\u0930\u093e \u092b\u094b\u0921\u093c \u0926\u0947\u0924\u0947 \u0939\u0948\u0902? \u2014 \u0928 \u0915\u093f \u0906\u0935\u0947\u0917 \u0915\u0947 \u0907\u0932\u093e\u091c \u0915\u0947 \u0924\u094c\u0930 \u092a\u0930\u0964",faq:[["\u0915\u094d\u092f\u093e \u092a\u0902\u092a\u094b\u0902 \u0915\u0940 \u0915\u094b\u0908 \u0938\u092c\u0938\u0947 \u0905\u091a\u094d\u091b\u0940 \u0938\u0902\u0916\u094d\u092f\u093e \u0939\u094b\u0924\u0940 \u0939\u0948?","\u092e\u094b\u091f\u0947 \u0924\u094c\u0930 \u092a\u0930 \u0939\u093e\u0901: \u0932\u0902\u092c\u0940 \u0926\u094c\u0921\u093c \u092e\u0947\u0902 \u0938\u092c\u0938\u0947 \u0905\u091a\u094d\u091b\u0940 \u0930\u0923\u0928\u0940\u0924\u093f \u092f\u0939\u0940 \u0939\u0948 \u0915\u093f \u0914\u0938\u0924 \u092b\u091f\u0928\u0947 \u0935\u093e\u0932\u0947 \u092c\u093f\u0902\u0926\u0941 \u0938\u0947 \u0925\u094b\u0921\u093c\u093e \u092a\u0939\u0932\u0947 \u092a\u0948\u0938\u093e \u091c\u092e\u093e \u0915\u0930 \u0932\u0947\u0902, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u091c\u094b\u0916\u093f\u092e \u092c\u0922\u093c\u0928\u0947 \u0915\u0947 \u0938\u093e\u0925 \u0939\u0930 \u0905\u0924\u093f\u0930\u093f\u0915\u094d\u0924 \u092a\u0902\u092a \u0915\u0940 \u0915\u093c\u0940\u092e\u0924 \u0918\u091f\u0924\u0940 \u091c\u093e\u0924\u0940 \u0939\u0948\u0964 \u092a\u0930 \u0905\u0938\u0932\u0940 \u0938\u091f\u0940\u0915 \u092c\u093f\u0902\u0926\u0941 \u091b\u093f\u092a\u093e \u0930\u0939\u0924\u093e \u0939\u0948 \u0914\u0930 \u0917\u0941\u092c\u094d\u092c\u093e\u0930\u094b\u0902 \u0915\u0947 \u092a\u094d\u0930\u0915\u093e\u0930 \u0915\u0947 \u0938\u093e\u0925 \u092c\u0926\u0932\u0924\u093e \u0939\u0948 \u2014 \u092f\u0939\u0940 \u0924\u094b \u0907\u0938 \u0916\u0947\u0932 \u0915\u093e \u092a\u0942\u0930\u093e \u092e\u0915\u093c\u0938\u0926 \u0939\u0948\u0964"],["\u0915\u094d\u092f\u093e \u0907\u0938\u0938\u0947 \u092e\u0948\u0902 \u0905\u0938\u0932 \u091c\u093c\u093f\u0902\u0926\u0917\u0940 \u092e\u0947\u0902 \u0915\u092e \u0906\u0935\u0947\u0917\u0940 \u0939\u094b \u091c\u093e\u090a\u0901\u0917\u093e?","\u0907\u0938\u0915\u093e \u0915\u094b\u0908 \u0920\u094b\u0938 \u0938\u092c\u0942\u0924 \u0928\u0939\u0940\u0902 \u0939\u0948\u0964 \u0906\u092a \u0907\u0938 \u0916\u0947\u0932 \u0915\u0947 \u092d\u0940\u0924\u0930 \u091c\u094b\u0916\u093f\u092e \u0924\u094c\u0932\u0928\u0947 \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u090f\u0901\u0917\u0947, \u092a\u0930 \u0905\u0938\u0932 \u091c\u093c\u093f\u0902\u0926\u0917\u0940 \u0915\u0947 \u092b\u093c\u0948\u0938\u0932\u094b\u0902 \u0924\u0915 \u0907\u0938\u0915\u093e \u0938\u094d\u0925\u093e\u0928\u093e\u0902\u0924\u0930\u0923 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0922\u0902\u0917 \u0938\u0947 \u0928\u0939\u0940\u0902 \u0926\u093f\u0916\u093e \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0939\u092e \u0910\u0938\u093e \u0935\u093e\u0926\u093e \u0928\u0939\u0940\u0902 \u0915\u0930\u0924\u0947\u0964"],["\u0915\u094d\u092f\u093e \u0915\u093f\u0938\u0940 \u0917\u0941\u092c\u094d\u092c\u093e\u0930\u0947 \u0915\u093e \u092b\u091f \u091c\u093e\u0928\u093e \u090f\u0915 \u0917\u093c\u0932\u0924\u0940 \u0939\u0948?","\u091c\u093c\u0930\u0942\u0930\u0940 \u0928\u0939\u0940\u0902\u0964 \u0905\u0917\u0930 \u0906\u092a \u0915\u092d\u0940 \u0915\u094b\u0908 \u0917\u0941\u092c\u094d\u092c\u093e\u0930\u093e \u0928\u0939\u0940\u0902 \u092b\u094b\u0921\u093c\u0924\u0947, \u0924\u094b \u0932\u0917\u092d\u0917 \u0924\u092f \u0939\u0948 \u0915\u093f \u0906\u092a \u0939\u0926 \u0938\u0947 \u091c\u0932\u094d\u0926\u0940 \u092a\u0948\u0938\u093e \u092d\u0941\u0928\u093e \u0930\u0939\u0947 \u0939\u0948\u0902 \u0914\u0930 \u0905\u0902\u0915 \u091b\u094b\u0921\u093c \u0930\u0939\u0947 \u0939\u0948\u0902; \u0938\u092e\u091d\u0926\u093e\u0930\u0940 \u092d\u0930\u0940 \u0938\u0940\u092e\u093e \u0915\u0947 \u092a\u093e\u0938 \u092b\u0941\u0932\u093e\u0928\u0947 \u0915\u0940 \u0915\u093c\u0940\u092e\u0924 \u0915\u0947 \u0924\u094c\u0930 \u092a\u0930 \u0915\u0941\u091b \u0917\u0941\u092c\u094d\u092c\u093e\u0930\u094b\u0902 \u0915\u093e \u092b\u091f\u0928\u093e \u0924\u094b \u0938\u094d\u0935\u093e\u092d\u093e\u0935\u093f\u0915 \u0939\u0948\u0964"]],variants:"\u0906\u092e \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0930\u0902\u0917\u094b\u0902 \u0938\u0947 \u091a\u093f\u0939\u094d\u0928\u093f\u0924 \u092b\u091f\u0928\u0947 \u0915\u0940 \u0938\u0902\u092d\u093e\u0935\u0928\u093e \u092c\u0926\u0932\u0924\u0947 \u0939\u0948\u0902 (\u0915\u0941\u091b \u0917\u0941\u092c\u094d\u092c\u093e\u0930\u0947 \u0915\u0939\u0940\u0902 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u091c\u094b\u0916\u093f\u092e \u092d\u0930\u0947 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902), \u090f\u0915 \u0938\u094d\u0935\u091a\u093e\u0932\u093f\u0924 \u092e\u094b\u0921 \u091c\u094b\u0921\u093c\u0924\u0947 \u0939\u0948\u0902 \u091c\u093f\u0938\u092e\u0947\u0902 \u0906\u092a \u092a\u0902\u092a\u094b\u0902 \u0915\u0940 \u0938\u0902\u0916\u094d\u092f\u093e \u092a\u0939\u0932\u0947 \u0938\u0947 \u0924\u092f \u0915\u0930 \u0926\u0947\u0924\u0947 \u0939\u0948\u0902, \u092f\u0941\u0935\u093e\u0913\u0902 \u0915\u0947 \u0905\u0928\u0941\u0915\u0942\u0932 \u0938\u0902\u0938\u094d\u0915\u0930\u0923 (BART-Y) \u0915\u093e\u092e \u092e\u0947\u0902 \u0932\u0947\u0924\u0947 \u0939\u0948\u0902, \u092f\u093e \u092a\u0948\u0938\u0947 \u0915\u0940 \u091c\u0917\u0939 \u0905\u0902\u0915 \u0930\u0916 \u0926\u0947\u0924\u0947 \u0939\u0948\u0902\u0964 \u0936\u094b\u0927 \u0915\u0947 \u0932\u093f\u090f \u0935\u0930\u094d\u091a\u0941\u0905\u0932-\u0930\u093f\u092f\u0932\u093f\u091f\u0940 \u0914\u0930 \u092e\u0938\u094d\u0924\u093f\u0937\u094d\u0915-\u0907\u092e\u0947\u091c\u093f\u0902\u0917 \u0935\u093e\u0932\u0947 \u0930\u0942\u092a\u093e\u0902\u0924\u0930 \u092d\u0940 \u092e\u094c\u091c\u0942\u0926 \u0939\u0948\u0902\u0964"},zh:{about:"BART\uff1a\u98ce\u9669\u6c14\u7403\uff0c\u662f\u4e00\u6b3e\u5efa\u7acb\u5728\u201c\u6c14\u7403\u6a21\u62df\u98ce\u9669\u4efb\u52a1\u201d\u4e4b\u4e0a\u7684\u51b3\u7b56\u6e38\u620f\u3002\u4f60\u4e00\u6b21\u4e00\u4e0b\u5730\u7ed9\u4e00\u4e2a\u865a\u62df\u6c14\u7403\u6253\u6c14\uff1b\u6bcf\u6253\u4e00\u4e0b\u90fd\u4f1a\u5f80\u4e34\u65f6\u5956\u6c60\u91cc\u52a0\u94b1\uff0c\u4f46\u4e5f\u4f1a\u628a\u6c14\u7403\u7206\u6389\u7684\u6982\u7387\u5f80\u4e0a\u63a8\u4e00\u70b9\u3002\u4f60\u53ef\u4ee5\u5728\u4efb\u4f55\u65f6\u523b\u628a\u5956\u6c60\u91cc\u7684\u94b1\u6536\u5165\u56ca\u4e2d\uff0c\u4e5f\u53ef\u4ee5\u640f\u4e00\u628a\u535a\u53d6\u66f4\u591a\u2014\u2014\u53ef\u4e00\u65e6\u5b83\u5148\u7206\u4e86\uff0c\u8fd9\u4e2a\u6c14\u7403\u91cc\u7684\u94b1\u5c31\u5168\u6ca1\u4e86\u3002",benefit:"\u5b83\u8bad\u7ec3\u5728\u4e0d\u786e\u5b9a\u4e0b\u7684\u98ce\u9669\u6821\u51c6\uff1a\u5728\u4e0d\u65ad\u589e\u957f\u7684\u56de\u62a5\u548c\u4e0d\u65ad\u4e0a\u5347\u7684\u635f\u5931\u6982\u7387\u4e4b\u95f4\u6743\u8861\uff0c\u5e76\u61c2\u5f97\u4f55\u65f6\u8be5\u6536\u624b\u3002\u4f60\u8fd8\u4f1a\u7ec3\u4e60\u5956\u8d4f\u654f\u611f\u6027\u548c\u51b2\u52a8\u63a7\u5236\uff0c\u56e0\u4e3a\u806a\u660e\u7684\u505a\u6cd5\u662f\u5728\u8d2a\u5fc3\u8ba9\u4f60\u8f93\u6389\u8fd9\u4e00\u8f6e\u4e4b\u524d\u5c31\u628a\u94b1\u5151\u73b0\u3002",history:"\u8fd9\u9879\u4efb\u52a1\u5728 2000 \u5e74\u4ee3\u521d\u7531\u5b66\u9662\u6d3e\u5fc3\u7406\u5b66\u521b\u7acb\uff0c\u4f5c\u4e3a\u98ce\u9669\u95ee\u5377\u7684\u4e00\u79cd\u884c\u4e3a\u66ff\u4ee3\u65b9\u6848\u2014\u2014\u5728\u95ee\u5377\u91cc\uff0c\u4eba\u4eec\u5e38\u5e38\u8c0e\u62a5\u81ea\u5df1\u771f\u5b9e\u6709\u591a\u9c81\u83bd\u3002\u5b83\u8fc5\u901f\u4f20\u904d\u6210\u763e\u3001\u51b2\u52a8\u6027\u548c\u9752\u5c11\u5e74\u7814\u7a76\u9886\u57df\uff0c\u88ab\u6539\u7f16\u51fa\u9752\u5c11\u5e74\u7248\uff08BART-Y\uff09\u3001\u81ea\u52a8\u7248\u548c\u795e\u7ecf\u5f71\u50cf\u7248\uff0c\u6700\u7ec8\u6210\u4e3a\u4e00\u9879\u6d41\u884c\u7684\u6e38\u620f\u5316\u7ec3\u4e60\u3002",creator:"\u5b83\u7531\u9a6c\u91cc\u5170\u5927\u5b66\u7684 Carl W. Lejuez \u53ca\u540c\u4e8b\u5f00\u53d1\uff0c\u4e8e 2002 \u5e74\u9996\u6b21\u53d1\u8868\u5728\u300aJournal of Experimental Psychology: Applied\u300b\u4e0a\u3002Lejuez \u66fe\u8bf4\uff0c\u8fd9\u4e2a\u60f3\u6cd5\u6765\u81ea\u770b\u4eba\u4eec\u5728\u96c6\u5e02\u4e0a\u7ed9\u6c14\u7403\u6253\u6c14\uff0c\u6ce8\u610f\u5230\u6709\u4e9b\u4eba\u65e9\u65e9\u5c31\u505c\u624b\uff0c\u800c\u53e6\u4e00\u4e9b\u4eba\u5374\u4e00\u76f4\u6253\u5230\u6c14\u7403\u7206\u6389\u3002",methods:"\u5728\u6bcf\u4e2a\u6c14\u7403\u4e4b\u524d\u5c31\u5b9a\u4e0b\u4e00\u4e2a\u76ee\u6807\u6253\u6c14\u6b21\u6570\uff0c\u56f4\u7ed5\u8fd9\u4e2a\u6570\u628a\u94b1\u5151\u73b0\uff0c\u800c\u4e0d\u662f\u4e00\u4e0b\u4e00\u4e0b\u5730\u4e34\u573a\u53cd\u5e94\u3002\u5927\u81f4\u8bb0\u4f4f\u6c14\u7403\u901a\u5e38\u6253\u5230\u591a\u5c11\u4e0b\u4f1a\u7206\uff0c\u628a\u76ee\u6807\u5b9a\u5728\u7565\u4f4e\u4e8e\u90a3\u4e2a\u6570\uff1b\u4e0d\u8981\u5728\u4e00\u6b21\u7206\u6389\u4e4b\u540e\u9760\u66f4\u731b\u5730\u6253\u6c14\u53bb\u8ffd\u56de\u635f\u5931\u2014\u2014\u90a3\u6070\u6070\u662f\u4eba\u4eec\u6253\u8fc7\u5934\u7684\u65f6\u5019\u3002",duration:"\u77ed\u65f6\u6bb5\u6548\u679c\u6700\u597d\u2014\u2014\u5927\u7ea6 20 \u5230 40 \u4e2a\u6c14\u7403\u3001\u4e94\u5230\u5341\u5206\u949f\uff0c\u5c31\u8db3\u591f\u4e86\u3002\u628a\u5b83\u5f53\u4f5c\u6bcf\u5468\u51e0\u6b21\u3001\u5076\u5c14\u505a\u4e00\u4e0b\u7684\u51b3\u7b56\u70ed\u8eab\uff0c\u800c\u4e0d\u662f\u6bcf\u5929\u53bb\u78e8\u7684\u4e1c\u897f\u3002",research:"\u8bc1\u636e\u6700\u5f3a\u7684\uff0c\u662f\u4f60\u80fd\u6599\u5230\u7684\u90a3\u4e9b\uff1a\u8fd9\u9879\u4efb\u52a1\u80fd\u53ef\u9760\u5730\u5728\u5b9e\u9a8c\u5ba4\u91cc\u6d4b\u91cf\u5192\u9669\u884c\u4e3a\uff0c\u91cd\u6d4b\u4fe1\u5ea6\u5c1a\u53ef\uff0c\u800c\u4e14\u4eba\u4eec\u7684\u6253\u6c14\u6b21\u6570\u4e0e\u67d0\u4e9b\u73b0\u5b9e\u884c\u4e3a\uff08\u5982\u5438\u70df\u3001\u7528\u836f\u548c\u8d4c\u535a\uff09\u5b58\u5728\u9002\u5ea6\u7684\u76f8\u5173\u3002\u4f46\u5b83\u4e0e\u771f\u5b9e\u751f\u6d3b\u51b3\u7b56\u7684\u5173\u8054\u65e2\u5f31\u53c8\u4e0d\u4e00\u81f4\uff0c\u4e0e\u81ea\u6211\u62a5\u544a\u7684\u98ce\u9669\u91cf\u8868\u4e5f\u543b\u5408\u5f97\u5f88\u5dee\uff0c\u800c\u4e14\u6709\u82e5\u5e72\u8bba\u6587\u6307\u51fa\u4e86\u65b9\u6cd5\u5b66\u548c\u4fe1\u5ea6\u4e0a\u7684\u95ee\u9898\u3002\u6ca1\u6709\u53ef\u9760\u8bc1\u636e\u8868\u660e\u7ec3\u4e60\u5b83\u80fd\u8ba9\u4f60\u5728\u6e38\u620f\u4e4b\u5916\u66f4\u4e0d\u51b2\u52a8\u6216\u66f4\u4f1a\u505a\u51b3\u5b9a\uff0c\u6240\u4ee5\u5bf9\u4efb\u4f55\u201c\u8bad\u7ec3\u4f60\u7684\u5192\u9669\u503e\u5411\u201d\u7684\u627f\u8bfa\u90fd\u8981\u4fdd\u6301\u8c28\u614e\u3002",rec:"\u73a9\u5b83\u662f\u4e3a\u4e86\u5bdf\u89c9\u4f60\u81ea\u5df1\u7684\u6a21\u5f0f\u2014\u2014\u4f60\u662f\u5151\u73b0\u5f97\u592a\u65e9\uff0c\u8fd8\u662f\u7206\u5f97\u592a\u9891\u7e41\uff1f\u2014\u2014\u800c\u4e0d\u662f\u628a\u5b83\u5f53\u4f5c\u6cbb\u51b2\u52a8\u7684\u826f\u65b9\u3002",faq:[["\u6709\u6ca1\u6709\u4e00\u4e2a\u6700\u4f18\u7684\u6253\u6c14\u6b21\u6570\uff1f","\u5927\u81f4\u4e0a\u6709\uff1a\u957f\u671f\u6765\u770b\u6700\u4f18\u7684\u7b56\u7565\uff0c\u662f\u5728\u5e73\u5747\u7206\u88c2\u70b9\u4e4b\u524d\u7a0d\u5fae\u6536\u624b\uff0c\u56e0\u4e3a\u968f\u7740\u98ce\u9669\u6500\u5347\uff0c\u6bcf\u591a\u6253\u4e00\u4e0b\u7684\u4ef7\u503c\u90fd\u5728\u53d8\u5c0f\u3002\u4f46\u90a3\u4e2a\u7cbe\u786e\u7684\u751c\u871c\u70b9\u662f\u9690\u85cf\u7684\uff0c\u800c\u4e14\u5728\u4e0d\u540c\u7c7b\u578b\u7684\u6c14\u7403\u4e4b\u95f4\u4f1a\u53d8\u5316\uff0c\u8fd9\u6b63\u662f\u5168\u90e8\u7684\u610f\u4e49\u6240\u5728\u3002"],["\u8fd9\u4f1a\u8ba9\u6211\u5728\u73b0\u5b9e\u751f\u6d3b\u4e2d\u66f4\u4e0d\u51b2\u52a8\u5417\uff1f","\u6ca1\u6709\u624e\u5b9e\u7684\u8bc1\u636e\u652f\u6301\u8fd9\u4e00\u70b9\u3002\u4f60\u4f1a\u5728\u8fd9\u6b3e\u6e38\u620f\u91cc\u53d8\u5f97\u66f4\u64c5\u957f\u5224\u65ad\u98ce\u9669\uff0c\u4f46\u5411\u73b0\u5b9e\u51b3\u7b56\u7684\u8fc1\u79fb\u5e76\u672a\u88ab\u53ef\u9760\u5730\u8bc1\u660e\uff0c\u6240\u4ee5\u6211\u4eec\u4e0d\u4f5c\u8fd9\u79cd\u627f\u8bfa\u3002"],["\u5f04\u7206\u4e00\u4e2a\u6c14\u7403\u7b97\u662f\u5931\u8bef\u5417\uff1f","\u4e0d\u4e00\u5b9a\u3002\u5982\u679c\u4f60\u4ece\u4e0d\u5f04\u7206\u4e00\u4e2a\u6c14\u7403\uff0c\u90a3\u51e0\u4e4e\u53ef\u4ee5\u80af\u5b9a\u4f60\u5151\u73b0\u5f97\u592a\u65e9\u3001\u628a\u5206\u6570\u7559\u5728\u4e86\u684c\u4e0a\uff1b\u8981\u5728\u806a\u660e\u7684\u6781\u9650\u9644\u8fd1\u6253\u6c14\uff0c\u6709\u4e9b\u7206\u88c2\u5c31\u662f\u4e3a\u6b64\u4ed8\u51fa\u7684\u4ee3\u4ef7\u3002"]],variants:"\u5e38\u89c1\u7684\u7248\u672c\u4f1a\u6539\u53d8\u7528\u989c\u8272\u6807\u8bb0\u7684\u7206\u88c2\u6982\u7387\uff08\u6709\u4e9b\u6c14\u7403\u5371\u9669\u5f97\u591a\uff09\uff0c\u52a0\u5165\u4e00\u4e2a\u53ef\u4ee5\u9884\u8bbe\u6253\u6c14\u6b21\u6570\u7684\u81ea\u52a8\u6a21\u5f0f\uff0c\u4f7f\u7528\u9002\u5408\u9752\u5c11\u5e74\u7684\u7248\u672c\uff08BART-Y\uff09\uff0c\u6216\u7528\u79ef\u5206\u66ff\u4ee3\u91d1\u94b1\u3002\u7814\u7a76\u7528\u7684\u865a\u62df\u73b0\u5b9e\u7248\u548c\u8111\u6210\u50cf\u7248\u4e5f\u662f\u5b58\u5728\u7684\u3002"}},"choice-rt":{ru:{about:"\xabChoice RT: Speed\xbb - \u044d\u0442\u043e \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0430 \u0440\u0435\u0430\u043a\u0446\u0438\u0438, \u0433\u0434\u0435 \u043e\u0442\u0432\u0435\u0442\u043e\u0432 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e. \u041f\u043e\u044f\u0432\u043b\u044f\u0435\u0442\u0441\u044f \u0441\u0438\u0433\u043d\u0430\u043b - \u0446\u0432\u0435\u0442, \u0441\u0442\u0440\u0435\u043b\u043a\u0430, \u0441\u0442\u043e\u0440\u043e\u043d\u0430 \u044d\u043a\u0440\u0430\u043d\u0430 - \u0438 \u043d\u0443\u0436\u043d\u043e \u043a\u0430\u043a \u043c\u043e\u0436\u043d\u043e \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u043d\u0430\u0436\u0430\u0442\u044c \u043f\u043e\u0434\u0445\u043e\u0434\u044f\u0449\u0443\u044e \u043a\u043d\u043e\u043f\u043a\u0443, \u043d\u0435 \u0443\u0433\u0430\u0434\u044b\u0432\u0430\u044f. \u0412 \u043e\u0442\u043b\u0438\u0447\u0438\u0435 \u043e\u0442 \u043f\u0440\u043e\u0441\u0442\u043e\u0439 \u0440\u0435\u0430\u043a\u0446\u0438\u0438, \u0433\u0434\u0435 \u0432\u044b \u043e\u0442\u043a\u043b\u0438\u043a\u0430\u0435\u0442\u0435\u0441\u044c \u043d\u0430 \u043b\u044e\u0431\u043e\u0439 \u0441\u0438\u0433\u043d\u0430\u043b, \u0437\u0434\u0435\u0441\u044c \u0441\u043d\u0430\u0447\u0430\u043b\u0430 \u043d\u0430\u0434\u043e \u043f\u043e\u043d\u044f\u0442\u044c, \u043a\u0430\u043a\u043e\u0439 \u0438\u043c\u0435\u043d\u043d\u043e \u044d\u0442\u043e \u0441\u0438\u0433\u043d\u0430\u043b, \u0438 \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442\u0441\u044f \u0438\u043c\u0435\u043d\u043d\u043e \u044d\u0442\u043e \u0440\u0435\u0448\u0435\u043d\u0438\u0435.",benefit:"\u0420\u0430\u0437\u0432\u0438\u0432\u0430\u0435\u0442 \u0440\u0435\u0430\u043a\u0446\u0438\u044e \u0432\u044b\u0431\u043e\u0440\u0430: \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u0441\u0432\u044f\u0437\u043a\u0438 \xab\u0443\u0432\u0438\u0434\u0435\u043b \u0441\u0438\u0433\u043d\u0430\u043b - \u043f\u043e\u043d\u044f\u043b, \u0447\u0442\u043e \u043e\u043d \u0437\u043d\u0430\u0447\u0438\u0442 - \u0437\u0430\u043f\u0443\u0441\u0442\u0438\u043b \u0432\u0435\u0440\u043d\u043e\u0435 \u0434\u0432\u0438\u0436\u0435\u043d\u0438\u0435\xbb. \u041f\u0440\u043e\u0449\u0435 \u0433\u043e\u0432\u043e\u0440\u044f, \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442\u0441\u044f \u0446\u0438\u043a\u043b \xab\u0440\u0435\u0448\u0438 \u0438 \u0441\u0434\u0435\u043b\u0430\u0439\xbb \u0438 \u0443\u0441\u0442\u043e\u0439\u0447\u0438\u0432\u043e\u0441\u0442\u044c \u043a \u0438\u043c\u043f\u0443\u043b\u044c\u0441\u0438\u0432\u043d\u044b\u043c \u043e\u0448\u0438\u0431\u043e\u0447\u043d\u044b\u043c \u043d\u0430\u0436\u0430\u0442\u0438\u044f\u043c, \u0430 \u043d\u0435 \u0433\u043e\u043b\u044b\u0439 \u0440\u0435\u0444\u043b\u0435\u043a\u0441.",history:"\u0417\u0430\u0434\u0430\u0447\u0430 \u0440\u0435\u0430\u043a\u0446\u0438\u0438 \u0432\u044b\u0431\u043e\u0440\u0430 \u0441\u0442\u043e\u0438\u0442 \u0443 \u0438\u0441\u0442\u043e\u043a\u043e\u0432 \u044d\u043a\u0441\u043f\u0435\u0440\u0438\u043c\u0435\u043d\u0442\u0430\u043b\u044c\u043d\u043e\u0439 \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u0438. \u0413\u043e\u043b\u043b\u0430\u043d\u0434\u0441\u043a\u0438\u0439 \u0444\u0438\u0437\u0438\u043e\u043b\u043e\u0433 \u0424. \u041a. \u0414\u043e\u043d\u0434\u0435\u0440\u0441 \u0438\u0437\u043c\u0435\u0440\u044f\u043b \u0435\u0451 \u0435\u0449\u0451 \u0432 1868 \u0433\u043e\u0434\u0443, \u0447\u0442\u043e\u0431\u044b \u0445\u0440\u043e\u043d\u043e\u043c\u0435\u0442\u0440\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u0440\u0430\u0431\u043e\u0442\u0443 \u0443\u043c\u0430, \u0430 \u0432 1950-\u0445 \u0437\u0430\u0434\u0430\u0447\u0430 \u0441\u0442\u0430\u043b\u0430 \u0446\u0435\u043d\u0442\u0440\u0430\u043b\u044c\u043d\u043e\u0439 \u0434\u043b\u044f \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u0438 \u043f\u0435\u0440\u0435\u0440\u0430\u0431\u043e\u0442\u043a\u0438 \u0438\u043d\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u0438: \u0432\u044b\u044f\u0441\u043d\u0438\u043b\u043e\u0441\u044c, \u0447\u0442\u043e \u0432\u0440\u0435\u043c\u044f \u0440\u0435\u0430\u043a\u0446\u0438\u0438 \u0437\u0430\u043a\u043e\u043d\u043e\u043c\u0435\u0440\u043d\u043e \u0440\u0430\u0441\u0442\u0451\u0442 \u043f\u043e \u043c\u0435\u0440\u0435 \u0434\u043e\u0431\u0430\u0432\u043b\u0435\u043d\u0438\u044f \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u043e\u0432 \u043e\u0442\u0432\u0435\u0442\u0430.",creator:"\u0423 \u0441\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u043e\u0439 \u0432\u0435\u0440\u0441\u0438\u0438 \u0432 \u043f\u0440\u0438\u043b\u043e\u0436\u0435\u043d\u0438\u0438 \u043d\u0435\u0442 \u0435\u0434\u0438\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0433\u043e \u0430\u0432\u0442\u043e\u0440\u0430 - \u044d\u0442\u043e \u043f\u0440\u044f\u043c\u043e\u0439 \u043f\u043e\u0442\u043e\u043c\u043e\u043a \u044d\u043a\u0441\u043f\u0435\u0440\u0438\u043c\u0435\u043d\u0442\u0430 \u0414\u043e\u043d\u0434\u0435\u0440\u0441\u0430 1868 \u0433\u043e\u0434\u0430. \u041a\u043b\u044e\u0447\u0435\u0432\u043e\u0439 \u043f\u0440\u0438\u043d\u0446\u0438\u043f, \u0447\u0442\u043e \u0432\u0440\u0435\u043c\u044f \u0440\u0435\u0430\u043a\u0446\u0438\u0438 \u0440\u0430\u0441\u0442\u0451\u0442 \u043b\u043e\u0433\u0430\u0440\u0438\u0444\u043c\u0438\u0447\u0435\u0441\u043a\u0438 \u0441 \u0447\u0438\u0441\u043b\u043e\u043c \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u043e\u0432, \u043d\u0430\u0437\u044b\u0432\u0430\u0435\u0442\u0441\u044f \u0437\u0430\u043a\u043e\u043d\u043e\u043c \u0425\u0438\u043a\u0430-\u0425\u0430\u0439\u043c\u0430\u043d\u0430 \u043f\u043e \u0438\u043c\u0435\u043d\u0430\u043c \u0423. \u042d. \u0425\u0438\u043a\u0430 (1952) \u0438 \u0420\u044d\u044f \u0425\u0430\u0439\u043c\u0430\u043d\u0430 (1953), \u043f\u0440\u0438\u0448\u0435\u0434\u0448\u0438\u0445 \u043a \u043d\u0435\u043c\u0443 \u043d\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043c\u043e.",methods:"\u0421\u043d\u0430\u0447\u0430\u043b\u0430 \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u044c, \u043f\u043e\u0442\u043e\u043c \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c: \u0431\u044b\u0441\u0442\u0440\u044b\u0439 \u043d\u0435\u0432\u0435\u0440\u043d\u044b\u0439 \u043e\u0442\u0432\u0435\u0442 \u0445\u0443\u0436\u0435 \u0447\u0443\u0442\u044c \u0431\u043e\u043b\u0435\u0435 \u043c\u0435\u0434\u043b\u0435\u043d\u043d\u043e\u0433\u043e \u0432\u0435\u0440\u043d\u043e\u0433\u043e. \u0414\u0435\u0440\u0436\u0438\u0442\u0435 \u043f\u0430\u043b\u044c\u0446\u044b \u043d\u0430 \u043a\u043b\u0430\u0432\u0438\u0448\u0430\u0445 \u043e\u0442\u0432\u0435\u0442\u0430, \u0441\u043c\u043e\u0442\u0440\u0438\u0442\u0435 \u0432 \u0446\u0435\u043d\u0442\u0440, \u0433\u0434\u0435 \u043f\u043e\u044f\u0432\u043b\u044f\u0435\u0442\u0441\u044f \u0441\u0438\u0433\u043d\u0430\u043b, \u0438 \u0440\u0435\u0430\u0433\u0438\u0440\u0443\u0439\u0442\u0435, \u0430 \u043d\u0435 \u043f\u0440\u0435\u0434\u0443\u0433\u0430\u0434\u044b\u0432\u0430\u0439\u0442\u0435. \u041f\u0435\u0440\u0435\u0434 \u0440\u0435\u043a\u043e\u0440\u0434\u043e\u043c \u0441\u0434\u0435\u043b\u0430\u0439\u0442\u0435 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0440\u0430\u0437\u043c\u0438\u043d\u043e\u0447\u043d\u044b\u0445 \u043a\u0440\u0443\u0433\u043e\u0432 \u0438 \u0441\u043b\u0435\u0434\u0438\u0442\u0435 \u0437\u0430 \u0434\u043e\u043b\u0435\u0439 \u043e\u0448\u0438\u0431\u043e\u043a, \u0430 \u043d\u0435 \u0442\u043e\u043b\u044c\u043a\u043e \u0437\u0430 \u0446\u0438\u0444\u0440\u043e\u0439 \u0432 \u043c\u0438\u043b\u043b\u0438\u0441\u0435\u043a\u0443\u043d\u0434\u0430\u0445.",duration:"\u041a\u043e\u0440\u043e\u0442\u043a\u043e \u0438 \u0447\u0430\u0441\u0442\u043e \u043b\u0443\u0447\u0448\u0435, \u0447\u0435\u043c \u0434\u043e\u043b\u0433\u043e \u0438 \u0440\u0435\u0434\u043a\u043e. \u0422\u0440\u0438-\u043f\u044f\u0442\u044c \u043c\u0438\u043d\u0443\u0442 \u0432 \u0434\u0435\u043d\u044c \u0438\u043b\u0438 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0431\u043b\u043e\u043a\u043e\u0432 \u043f\u043e 30-60 \u0440\u0435\u0430\u043a\u0446\u0438\u0439 - \u044d\u0442\u043e\u0433\u043e \u0445\u0432\u0430\u0442\u0430\u0435\u0442; \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u0440\u0435\u0430\u043a\u0446\u0438\u0438 \u0432\u044b\u0445\u043e\u0434\u0438\u0442 \u043d\u0430 \u043f\u043b\u0430\u0442\u043e \u0431\u044b\u0441\u0442\u0440\u043e, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u0435\u0436\u0435\u0434\u043d\u0435\u0432\u043d\u0430\u044f \u0440\u0435\u0433\u0443\u043b\u044f\u0440\u043d\u043e\u0441\u0442\u044c \u0432\u0430\u0436\u043d\u0435\u0435 \u0434\u043e\u043b\u0433\u0438\u0445 \u0437\u0430\u0445\u043e\u0434\u043e\u0432.",research:"\u0414\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u043d\u0435\u0435 \u0432\u0441\u0435\u0433\u043e \u0440\u043e\u0432\u043d\u043e \u0442\u043e, \u0447\u0435\u0433\u043e \u0438 \u0436\u0434\u0451\u0448\u044c: \u0441 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u043e\u0439 \u0432\u044b \u0437\u0430\u043c\u0435\u0442\u043d\u043e \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u0438 \u0442\u043e\u0447\u043d\u0435\u0435 \u0438\u043c\u0435\u043d\u043d\u043e \u0432 \u0437\u0430\u0434\u0430\u0447\u0430\u0445 \u043d\u0430 \u0440\u0435\u0430\u043a\u0446\u0438\u044e \u0432\u044b\u0431\u043e\u0440\u0430, \u0430 \u0441\u0432\u044f\u0437\u044c \u0425\u0438\u043a\u0430-\u0425\u0430\u0439\u043c\u0430\u043d\u0430 \u043c\u0435\u0436\u0434\u0443 \u0447\u0438\u0441\u043b\u043e\u043c \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u043e\u0432 \u0438 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c\u044e - \u043e\u0434\u0438\u043d \u0438\u0437 \u0441\u0430\u043c\u044b\u0445 \u043d\u0430\u0434\u0451\u0436\u043d\u044b\u0445 \u0444\u0430\u043a\u0442\u043e\u0432 \u0432 \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u0438. \u0417\u0430\u044f\u0432\u043b\u0435\u043d\u0438\u044f, \u0447\u0442\u043e \u0442\u0430\u043a\u0430\u044f \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0430 \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0438\u0442\u0441\u044f \u043d\u0430 \u043e\u0431\u0449\u0438\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0438\u043b\u0438 \xab\u043e\u0431\u0449\u0443\u044e \u0441\u043e\u043e\u0431\u0440\u0430\u0437\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c\xbb, \u0441\u043b\u0430\u0431\u044b: \u043a\u0440\u0443\u043f\u043d\u044b\u0435 \u043e\u0431\u0437\u043e\u0440\u044b \u0442\u0440\u0435\u043d\u0430\u0436\u0451\u0440\u043e\u0432 \u043c\u043e\u0437\u0433\u0430 \u043f\u043e\u0447\u0442\u0438 \u043d\u0435 \u043d\u0430\u0445\u043e\u0434\u044f\u0442 \u043d\u0430\u0434\u0451\u0436\u043d\u043e\u0433\u043e \u0434\u0430\u043b\u044c\u043d\u0435\u0433\u043e \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0430. \u0411\u043e\u043b\u0435\u0435 \u0443\u0437\u043a\u0430\u044f \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0430 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u0438 \u043e\u0431\u0440\u0430\u0431\u043e\u0442\u043a\u0438 \u0432 \u0447\u0430\u0441\u0442\u0438 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u0439 \u0441\u0432\u044f\u0437\u044b\u0432\u0430\u043b\u0430\u0441\u044c \u0441 \u0431\u044b\u0442\u043e\u0432\u043e\u0439 \u043f\u043e\u043b\u044c\u0437\u043e\u0439 - \u0432\u043e\u0436\u0434\u0435\u043d\u0438\u0435\u043c \u0438 \u0441\u043d\u0438\u0436\u0435\u043d\u0438\u0435\u043c \u0440\u0438\u0441\u043a\u0430 \u0434\u0435\u043c\u0435\u043d\u0446\u0438\u0438, - \u043d\u043e \u044d\u0442\u0438 \u0432\u044b\u0432\u043e\u0434\u044b \u0441\u043f\u043e\u0440\u043d\u044b \u0438 \u043d\u0435 \u0440\u0430\u0441\u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u044f\u044e\u0442\u0441\u044f \u043d\u0430 \u043e\u0431\u044b\u0447\u043d\u0443\u044e \u0438\u0433\u0440\u0443 \u043f\u0440\u043e \u0440\u0435\u0430\u043a\u0446\u0438\u044e \u0432\u044b\u0431\u043e\u0440\u0430, \u0442\u0430\u043a \u0447\u0442\u043e \u043a \u0433\u0440\u043e\u043c\u043a\u0438\u043c \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f\u043c \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u0435\u0441\u044c \u043e\u0441\u0442\u043e\u0440\u043e\u0436\u043d\u043e.",rec:"\u0421\u043d\u0430\u0447\u0430\u043b\u0430 \u0434\u043e\u0431\u0438\u0432\u0430\u0439\u0442\u0435\u0441\u044c \u043d\u0438\u0437\u043a\u043e\u0439 \u0434\u043e\u043b\u0438 \u043e\u0448\u0438\u0431\u043e\u043a; \u043c\u0438\u043b\u043b\u0438\u0441\u0435\u043a\u0443\u043d\u0434\u044b \u0441\u0430\u043c\u0438 \u043f\u0440\u043e\u0441\u044f\u0434\u0443\u0442, \u043a\u043e\u0433\u0434\u0430 \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u044c \u0441\u0442\u0430\u043d\u0435\u0442 \u0441\u0442\u0430\u0431\u0438\u043b\u044c\u043d\u043e\u0439.",faq:[["\u0427\u0435\u043c \u044d\u0442\u043e \u043e\u0442\u043b\u0438\u0447\u0430\u0435\u0442\u0441\u044f \u043e\u0442 \u0442\u0435\u0441\u0442\u0430 \u043d\u0430 \u043f\u0440\u043e\u0441\u0442\u0443\u044e \u0440\u0435\u0430\u043a\u0446\u0438\u044e?","\u041f\u0440\u043e\u0441\u0442\u043e\u0439 \u0442\u0435\u0441\u0442 \u043c\u0435\u0440\u044f\u0435\u0442, \u043a\u0430\u043a \u0431\u044b\u0441\u0442\u0440\u043e \u0432\u044b \u0440\u0435\u0430\u0433\u0438\u0440\u0443\u0435\u0442\u0435 \u043d\u0430 \u043e\u0434\u0438\u043d \u0438\u0437\u0432\u0435\u0441\u0442\u043d\u044b\u0439 \u0441\u0438\u0433\u043d\u0430\u043b - \u0432\u044b\u0431\u0438\u0440\u0430\u0442\u044c \u043d\u0435 \u043d\u0443\u0436\u043d\u043e. \u0417\u0434\u0435\u0441\u044c \u0432\u043e\u0437\u043c\u043e\u0436\u043d\u044b \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0441\u0438\u0433\u043d\u0430\u043b\u043e\u0432, \u0438 \u043d\u0443\u0436\u043d\u043e \u0432\u044b\u0431\u0440\u0430\u0442\u044c \u043f\u043e\u0434\u0445\u043e\u0434\u044f\u0449\u0438\u0439 \u043e\u0442\u0432\u0435\u0442, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u0434\u043e\u0431\u0430\u0432\u043b\u044f\u0435\u0442\u0441\u044f \u0432\u0440\u0435\u043c\u044f \u0440\u0435\u0448\u0435\u043d\u0438\u044f \u043f\u043e\u0432\u0435\u0440\u0445 \u0447\u0438\u0441\u0442\u043e\u0433\u043e \u0440\u0435\u0444\u043b\u0435\u043a\u0441\u0430."],["\u041f\u043e\u0447\u0435\u043c\u0443 \u044f \u043c\u0435\u0434\u043b\u0435\u043d\u043d\u0435\u0435, \u043a\u043e\u0433\u0434\u0430 \u043a\u043d\u043e\u043f\u043e\u043a \u0431\u043e\u043b\u044c\u0448\u0435?","\u042d\u0442\u043e \u0440\u0430\u0431\u043e\u0442\u0430\u0435\u0442 \u0437\u0430\u043a\u043e\u043d \u0425\u0438\u043a\u0430-\u0425\u0430\u0439\u043c\u0430\u043d\u0430: \u043a\u0430\u0436\u0434\u044b\u0439 \u043b\u0438\u0448\u043d\u0438\u0439 \u0432\u0430\u0440\u0438\u0430\u043d\u0442 \u0434\u043e\u0431\u0430\u0432\u043b\u044f\u0435\u0442 \u043f\u0440\u0438\u043c\u0435\u0440\u043d\u043e \u0444\u0438\u043a\u0441\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u0443\u044e \u043f\u0440\u0438\u0431\u0430\u0432\u043a\u0443 \u043a\u043e \u0432\u0440\u0435\u043c\u0435\u043d\u0438 \u0440\u0435\u0448\u0435\u043d\u0438\u044f, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u0440\u0435\u0430\u043a\u0446\u0438\u044f \u0440\u0430\u0441\u0442\u0451\u0442 \u0437\u0430\u043a\u043e\u043d\u043e\u043c\u0435\u0440\u043d\u043e, \u043f\u043e\u0447\u0442\u0438 \u043b\u043e\u0433\u0430\u0440\u0438\u0444\u043c\u0438\u0447\u0435\u0441\u043a\u0438. \u042d\u0442\u043e \u043d\u043e\u0440\u043c\u0430, \u0430 \u043d\u0435 \u043f\u0440\u0438\u0437\u043d\u0430\u043a, \u0447\u0442\u043e \u0432\u044b \u043f\u043b\u043e\u0445\u043e \u0441\u043f\u0440\u0430\u0432\u043b\u044f\u0435\u0442\u0435\u0441\u044c."],["\u0421\u0442\u0430\u043d\u0443 \u043b\u0438 \u044f \u0443\u043c\u043d\u0435\u0435 \u0438\u043b\u0438 \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u0432 \u043e\u0431\u044b\u0447\u043d\u043e\u0439 \u0436\u0438\u0437\u043d\u0438?","\u0412\u044b \u043d\u0430\u0434\u0451\u0436\u043d\u043e \u0441\u0442\u0430\u043d\u0435\u0442\u0435 \u043b\u0443\u0447\u0448\u0435 \u0432 \u044d\u0442\u043e\u0439 \u0438 \u043f\u043e\u0445\u043e\u0436\u0438\u0445 \u0437\u0430\u0434\u0430\u0447\u0430\u0445 \u043d\u0430 \u0440\u0435\u0430\u043a\u0446\u0438\u044e. \u0428\u0438\u0440\u043e\u043a\u043e\u0433\u043e \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0430 \u043d\u0430 \u043e\u0431\u0449\u0438\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0438\u043b\u0438 \u043f\u043e\u0432\u0441\u0435\u0434\u043d\u0435\u0432\u043d\u043e\u0441\u0442\u044c \u0434\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432\u0430 \u043d\u0435 \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u044e\u0442, \u0442\u0430\u043a \u0447\u0442\u043e \u0432\u043e\u0441\u043f\u0440\u0438\u043d\u0438\u043c\u0430\u0439\u0442\u0435 \u044d\u0442\u043e \u043a\u0430\u043a \u0442\u043e\u0447\u0435\u0447\u043d\u0443\u044e \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0443 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u0438, \u0430 \u043d\u0435 \u0430\u043f\u0433\u0440\u0435\u0439\u0434 \u043c\u043e\u0437\u0433\u0430."]],variants:"\u041e\u0431\u044b\u0447\u043d\u043e \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u044b \u043c\u0435\u043d\u044f\u044e\u0442 \u0442\u043e, \u0447\u0442\u043e \u043d\u0430\u0434\u043e \u0440\u0430\u0437\u043b\u0438\u0447\u0438\u0442\u044c: \u0446\u0432\u0435\u0442\u0430, \u0444\u0438\u0433\u0443\u0440\u044b, \u043d\u0430\u043f\u0440\u0430\u0432\u043b\u0435\u043d\u0438\u0435 \u0441\u0442\u0440\u0435\u043b\u043e\u043a, \u043f\u043e\u0437\u0438\u0446\u0438\u044e \u0441\u043b\u0435\u0432\u0430 \u0438\u043b\u0438 \u0441\u043f\u0440\u0430\u0432\u0430, \u0440\u0430\u0441\u043a\u043b\u0430\u0434\u043a\u0443 \u043f\u043e\u0434 \u0434\u0432\u0435 \u0440\u0443\u043a\u0438. \u0421\u043b\u043e\u0436\u043d\u044b\u0435 \u0440\u0435\u0436\u0438\u043c\u044b \u0434\u043e\u0431\u0430\u0432\u043b\u044f\u044e\u0442 \u0431\u043e\u043b\u044c\u0448\u0435 \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u043e\u0432, \u0441\u0443\u0436\u0430\u044e\u0442 \u043e\u043a\u043d\u043e \u0432\u0440\u0435\u043c\u0435\u043d\u0438 \u0438\u043b\u0438 \u043f\u043e\u0434\u0431\u0440\u0430\u0441\u044b\u0432\u0430\u044e\u0442 \xab\u0441\u0442\u043e\u043f\xbb-\u0441\u0438\u0433\u043d\u0430\u043b\u044b, \u043d\u0430 \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u043d\u0430\u0436\u0438\u043c\u0430\u0442\u044c \u043d\u0435\u043b\u044c\u0437\u044f, \u0441\u043c\u0435\u0448\u0438\u0432\u0430\u044f \u0440\u0435\u0430\u043a\u0446\u0438\u044e \u0432\u044b\u0431\u043e\u0440\u0430 \u0441 \u0442\u043e\u0440\u043c\u043e\u0436\u0435\u043d\u0438\u0435\u043c."},en:{about:"Choice RT: Speed is a reaction drill with more than one possible response. A signal appears - a colour, an arrow, a side of the screen - and you must pick the matching button as fast as you can without guessing. Unlike a simple reaction test where you just react to any signal, here you first have to decide which signal it is, and that decision is exactly what you are training.",benefit:"It sharpens choice reaction time: the speed of perceiving a stimulus, deciding what it means, and launching the correct motor response. In plain terms it trains the decide-then-act loop and your resistance to impulsive wrong taps, not raw reflex alone.",history:"The choice reaction task goes back to the birth of experimental psychology. The Dutch physiologist F. C. Donders measured it in 1868 to time mental events, and in the 1950s the task became central to information-processing psychology, when researchers showed that reaction time grows in an orderly way as you add more response options.",creator:"There is no single inventor of the modern app version; it is a direct descendant of Donders' 1868 choice reaction experiment. The core principle - that reaction time rises logarithmically with the number of choices - is the Hick-Hyman law, named after W. E. Hick (1952) and Ray Hyman (1953), who established it independently.",methods:"Prioritise accuracy first, then speed - a fast wrong answer is worse than a slightly slower right one. Keep your fingers resting on the response keys, fix your eyes on the centre where signals appear, and react rather than predict. Warm up for a few rounds before chasing a personal best, and watch your error rate, not just the millisecond number.",duration:"Short and frequent beats long and rare. Three to five minutes a day, or a few blocks of 30 to 60 reactions, is plenty; reaction speed plateaus quickly, so daily consistency matters more than marathon sessions.",research:"Evidence is strongest for exactly what you would expect - with practice you get measurably faster and more accurate on choice reaction tasks themselves, and the Hick-Hyman relationship between choices and speed is one of the most robust findings in psychology. Claims that this kind of training transfers to general intelligence or broad mental sharpness are weak: large reviews of brain training find little reliable far transfer. Narrower speed-of-processing training has been linked in some trials to everyday benefits like driving and lower dementia risk, but those results are contested and do not generalise to a plain choice reaction game, so treat the grand promises with caution.",rec:"Chase a low error rate first; let the milliseconds drop on their own once your accuracy is steady.",faq:[["How is this different from a simple reaction test?","A simple test measures how fast you react to a single known signal - you do not have to choose. Here several signals are possible and you must select the matching response, so it captures decision time on top of pure reflex."],["Why do I get slower when there are more buttons?","That is the Hick-Hyman law in action: each extra option adds a roughly fixed increment of decision time, so reaction time climbs in an orderly, near-logarithmic way as choices increase. It is normal, not a sign you are doing badly."],["Will this make me smarter or quicker in everyday life?","It will reliably make you better at this task and similar reaction tasks. Broad carryover to general intelligence or daily life is not well supported by the evidence, so enjoy it as targeted speed practice rather than a brain upgrade."]],variants:"Common variants change what you must discriminate: colours, shapes, directional arrows, left-versus-right position, or two-handed key mapping. Harder modes add more choices, shrink the time window, or throw in no-go signals you must withhold a response to, blending choice reaction with inhibition."},es:{about:"Choice RT: Speed es un ejercicio de reacci\xf3n con m\xe1s de una respuesta posible. Aparece una se\xf1al \u2014un color, una flecha, un lado de la pantalla\u2014 y debes pulsar el bot\xf3n que le corresponde lo m\xe1s r\xe1pido que puedas sin adivinar. A diferencia de una prueba de reacci\xf3n simple en la que solo reaccionas ante cualquier se\xf1al, aqu\xed primero tienes que decidir de qu\xe9 se\xf1al se trata, y esa decisi\xf3n es exactamente lo que est\xe1s entrenando.",benefit:"Afina el tiempo de reacci\xf3n de elecci\xf3n: la velocidad para percibir un est\xedmulo, decidir qu\xe9 significa y lanzar la respuesta motora correcta. Dicho en plata, entrena el bucle de decidir-y-actuar y tu resistencia a los toques err\xf3neos impulsivos, no solo el reflejo en bruto.",history:"La tarea de reacci\xf3n de elecci\xf3n se remonta al nacimiento de la psicolog\xeda experimental. El fisi\xf3logo neerland\xe9s F. C. Donders la midi\xf3 en 1868 para cronometrar los procesos mentales, y en los a\xf1os 50 la tarea se volvi\xf3 central en la psicolog\xeda del procesamiento de la informaci\xf3n, cuando los investigadores demostraron que el tiempo de reacci\xf3n crece de forma ordenada a medida que a\xf1ades m\xe1s opciones de respuesta.",creator:"No hay un \xfanico inventor de la versi\xf3n moderna en aplicaci\xf3n; es un descendiente directo del experimento de reacci\xf3n de elecci\xf3n de Donders de 1868. El principio central \u2014que el tiempo de reacci\xf3n aumenta logar\xedtmicamente con el n\xfamero de opciones\u2014 es la ley de Hick-Hyman, llamada as\xed por W. E. Hick (1952) y Ray Hyman (1953), que la establecieron de forma independiente.",methods:"Prioriza primero la precisi\xf3n y luego la velocidad: una respuesta r\xe1pida pero err\xf3nea es peor que una correcta algo m\xe1s lenta. Mant\xe9n los dedos apoyados sobre las teclas de respuesta, fija la vista en el centro donde aparecen las se\xf1ales y reacciona en lugar de predecir. Calienta unas cuantas rondas antes de ir a por tu r\xe9cord personal, y vigila tu tasa de errores, no solo la cifra de milisegundos.",duration:"Lo corto y frecuente gana a lo largo y espor\xe1dico. De tres a cinco minutos al d\xeda, o unos pocos bloques de 30 a 60 reacciones, bastan; la velocidad de reacci\xf3n se estanca r\xe1pido, as\xed que la constancia diaria importa m\xe1s que las sesiones maratonianas.",research:"La evidencia es m\xe1s fuerte para justo lo que cabr\xeda esperar: con la pr\xe1ctica te vuelves de forma medible m\xe1s r\xe1pido y preciso en las propias tareas de reacci\xf3n de elecci\xf3n, y la relaci\xf3n de Hick-Hyman entre opciones y velocidad es uno de los hallazgos m\xe1s robustos de la psicolog\xeda. Las afirmaciones de que este tipo de entrenamiento se transfiere a la inteligencia general o a una agudeza mental amplia son d\xe9biles: las grandes revisiones del entrenamiento mental encuentran poca transferencia lejana fiable. Un entrenamiento m\xe1s acotado de la velocidad de procesamiento se ha asociado en algunos ensayos a beneficios cotidianos como conducir y menor riesgo de demencia, pero esos resultados est\xe1n en discusi\xf3n y no se generalizan a un simple juego de reacci\xf3n de elecci\xf3n, as\xed que toma las grandes promesas con cautela.",rec:"Persigue primero una tasa de errores baja; deja que los milisegundos bajen por s\xed solos una vez que tu precisi\xf3n sea estable.",faq:[["\xbfEn qu\xe9 se diferencia esto de una prueba de reacci\xf3n simple?","Una prueba simple mide con qu\xe9 rapidez reaccionas ante una \xfanica se\xf1al conocida: no tienes que elegir. Aqu\xed son posibles varias se\xf1ales y debes seleccionar la respuesta que corresponde, as\xed que captura el tiempo de decisi\xf3n por encima del reflejo puro."],["\xbfPor qu\xe9 voy m\xe1s lento cuando hay m\xe1s botones?","Es la ley de Hick-Hyman en acci\xf3n: cada opci\xf3n extra a\xf1ade un incremento m\xe1s o menos fijo de tiempo de decisi\xf3n, as\xed que el tiempo de reacci\xf3n sube de forma ordenada, casi logar\xedtmica, a medida que aumentan las opciones. Es normal, no se\xf1al de que lo est\xe9s haciendo mal."],["\xbfEsto me har\xe1 m\xe1s inteligente o m\xe1s r\xe1pido en la vida diaria?","Te har\xe1 de forma fiable mejor en esta tarea y en tareas de reacci\xf3n parecidas. La transferencia amplia a la inteligencia general o a la vida cotidiana no est\xe1 bien respaldada por la evidencia, as\xed que disfr\xfatalo como pr\xe1ctica de velocidad espec\xedfica y no como una mejora cerebral."]],variants:"Las variantes habituales cambian lo que debes discriminar: colores, formas, flechas direccionales, posici\xf3n izquierda-derecha o asignaci\xf3n de teclas a dos manos. Los modos m\xe1s dif\xedciles a\xf1aden m\xe1s opciones, encogen la ventana de tiempo o introducen se\xf1ales de no-respuesta ante las que debes contenerte, mezclando la reacci\xf3n de elecci\xf3n con la inhibici\xf3n."},de:{about:"Choice RT: Speed ist eine Reaktions\xfcbung mit mehr als einer m\xf6glichen Antwort. Ein Signal erscheint \u2014 eine Farbe, ein Pfeil, eine Bildschirmseite \u2014 und du musst die passende Schaltfl\xe4che so schnell wie m\xf6glich w\xe4hlen, ohne zu raten. Anders als bei einem einfachen Reaktionstest, bei dem du nur auf irgendein Signal reagierst, musst du hier zuerst entscheiden, welches Signal es ist, und genau diese Entscheidung trainierst du.",benefit:"Sie sch\xe4rft die Wahlreaktionszeit: die Geschwindigkeit, einen Reiz wahrzunehmen, zu entscheiden, was er bedeutet, und die richtige motorische Antwort abzufeuern. Schlicht gesagt trainiert sie die Schleife aus Entscheiden-dann-Handeln und deine Widerstandskraft gegen impulsive Fehltipper, nicht den reinen Reflex allein.",history:"Die Wahlreaktionsaufgabe reicht bis zur Geburt der experimentellen Psychologie zur\xfcck. Der niederl\xe4ndische Physiologe F. C. Donders ma\xdf sie 1868, um geistige Vorg\xe4nge zeitlich zu erfassen, und in den 1950er Jahren r\xfcckte die Aufgabe ins Zentrum der Informationsverarbeitungs-Psychologie, als Forscher zeigten, dass die Reaktionszeit auf geordnete Weise w\xe4chst, sobald man mehr Antwortm\xf6glichkeiten hinzuf\xfcgt.",creator:"Es gibt keinen einzelnen Erfinder der modernen App-Version; sie ist ein direkter Nachkomme von Donders' Wahlreaktionsexperiment von 1868. Das Kernprinzip \u2014 dass die Reaktionszeit logarithmisch mit der Zahl der Wahlm\xf6glichkeiten steigt \u2014 ist das Hick-Hyman-Gesetz, benannt nach W. E. Hick (1952) und Ray Hyman (1953), die es unabh\xe4ngig voneinander begr\xfcndeten.",methods:"Stelle zuerst die Genauigkeit \xfcber die Geschwindigkeit \u2014 eine schnelle falsche Antwort ist schlimmer als eine etwas langsamere richtige. Lass deine Finger auf den Antworttasten ruhen, fixiere die Mitte, wo die Signale erscheinen, und reagiere, statt vorherzusagen. W\xe4rme dich ein paar Runden lang auf, bevor du eine pers\xf6nliche Bestleistung jagst, und behalte deine Fehlerquote im Blick, nicht nur die Millisekundenzahl.",duration:"Kurz und h\xe4ufig schl\xe4gt lang und selten. Drei bis f\xfcnf Minuten am Tag oder ein paar Bl\xf6cke von 30 bis 60 Reaktionen reichen v\xf6llig; die Reaktionsgeschwindigkeit stagniert schnell, daher z\xe4hlt t\xe4gliche Best\xe4ndigkeit mehr als Marathonsitzungen.",research:"Die Evidenz ist genau f\xfcr das am st\xe4rksten, was man erwarten w\xfcrde \u2014 mit \xdcbung wirst du in Wahlreaktionsaufgaben selbst messbar schneller und genauer, und der Hick-Hyman-Zusammenhang zwischen Wahlm\xf6glichkeiten und Tempo ist einer der robustesten Befunde der Psychologie. Behauptungen, dass diese Art von Training auf allgemeine Intelligenz oder breite geistige Sch\xe4rfe \xfcbertrage, sind schwach: gro\xdfe \xdcbersichtsarbeiten zum Gehirntraining finden kaum verl\xe4sslichen Ferntransfer. Enger gefasstes Training der Verarbeitungsgeschwindigkeit wurde in einigen Studien mit Alltagsnutzen wie dem Autofahren und geringerem Demenzrisiko in Verbindung gebracht, doch diese Ergebnisse sind umstritten und lassen sich nicht auf ein schlichtes Wahlreaktionsspiel verallgemeinern, also begegne den gro\xdfen Versprechen mit Vorsicht.",rec:"Jage zuerst einer niedrigen Fehlerquote nach; lass die Millisekunden von allein fallen, sobald deine Genauigkeit best\xe4ndig ist.",faq:[["Wie unterscheidet sich das von einem einfachen Reaktionstest?","Ein einfacher Test misst, wie schnell du auf ein einzelnes bekanntes Signal reagierst \u2014 du musst nicht w\xe4hlen. Hier sind mehrere Signale m\xf6glich und du musst die passende Antwort ausw\xe4hlen, sodass die Entscheidungszeit zus\xe4tzlich zum reinen Reflex erfasst wird."],["Warum werde ich langsamer, wenn es mehr Schaltfl\xe4chen gibt?","Das ist das Hick-Hyman-Gesetz in Aktion: Jede zus\xe4tzliche Option f\xfcgt einen grob festen Zuwachs an Entscheidungszeit hinzu, sodass die Reaktionszeit auf geordnete, nahezu logarithmische Weise steigt, je mehr Wahlm\xf6glichkeiten es gibt. Das ist normal, kein Zeichen, dass du es schlecht machst."],["Macht mich das schlauer oder im Alltag schneller?","Es macht dich zuverl\xe4ssig besser in dieser Aufgabe und in \xe4hnlichen Reaktionsaufgaben. Ein breiter \xdcbertrag auf allgemeine Intelligenz oder den Alltag ist durch die Belege nicht gut gest\xfctzt, also genie\xdfe es als gezielte Tempo\xfcbung statt als Gehirn-Upgrade."]],variants:"\xdcbliche Abwandlungen ver\xe4ndern, was du unterscheiden musst: Farben, Formen, Richtungspfeile, Links-gegen-rechts-Position oder eine zweih\xe4ndige Tastenbelegung. Schwerere Modi f\xfcgen mehr Wahlm\xf6glichkeiten hinzu, verkleinern das Zeitfenster oder werfen No-go-Signale ein, bei denen du eine Antwort zur\xfcckhalten musst, und verbinden so Wahlreaktion mit Hemmung."},pt:{about:"Choice RT: Speed \xe9 um exerc\xedcio de rea\xe7\xe3o com mais de uma resposta poss\xedvel. Um sinal aparece \u2014 uma cor, uma seta, um lado da tela \u2014 e voc\xea precisa escolher o bot\xe3o correspondente o mais r\xe1pido que conseguir, sem chutar. Diferente de um teste de rea\xe7\xe3o simples, em que voc\xea apenas reage a qualquer sinal, aqui voc\xea primeiro tem de decidir qual sinal \xe9, e \xe9 exatamente essa decis\xe3o que voc\xea est\xe1 treinando.",benefit:"Afia o tempo de rea\xe7\xe3o de escolha: a velocidade de perceber um est\xedmulo, decidir o que ele significa e disparar a resposta motora correta. Em termos simples, treina o ciclo decidir-ent\xe3o-agir e sua resist\xeancia a toques errados impulsivos, n\xe3o apenas o reflexo bruto.",history:"A tarefa de rea\xe7\xe3o de escolha remonta ao nascimento da psicologia experimental. O fisiologista holand\xeas F. C. Donders a mediu em 1868 para cronometrar eventos mentais, e nos anos 1950 a tarefa tornou-se central para a psicologia do processamento de informa\xe7\xe3o, quando pesquisadores mostraram que o tempo de rea\xe7\xe3o cresce de modo ordenado conforme voc\xea acrescenta mais op\xe7\xf5es de resposta.",creator:"N\xe3o h\xe1 um \xfanico inventor da vers\xe3o moderna em aplicativo; ela \xe9 descendente direta do experimento de rea\xe7\xe3o de escolha de Donders, de 1868. O princ\xedpio central \u2014 que o tempo de rea\xe7\xe3o sobe logaritmicamente com o n\xfamero de escolhas \u2014 \xe9 a lei de Hick-Hyman, batizada em homenagem a W. E. Hick (1952) e Ray Hyman (1953), que a estabeleceram de forma independente.",methods:"Priorize a precis\xe3o primeiro, depois a velocidade \u2014 uma resposta r\xe1pida e errada \xe9 pior do que uma certa e um pouco mais lenta. Mantenha os dedos apoiados nas teclas de resposta, fixe os olhos no centro, onde os sinais aparecem, e reaja em vez de prever. Aque\xe7a por algumas rodadas antes de buscar um recorde pessoal, e observe sua taxa de erro, n\xe3o apenas o n\xfamero em milissegundos.",duration:"Curto e frequente bate longo e raro. Tr\xeas a cinco minutos por dia, ou alguns blocos de 30 a 60 rea\xe7\xf5es, bastam; a velocidade de rea\xe7\xe3o estabiliza rapidamente, ent\xe3o a const\xe2ncia di\xe1ria importa mais do que sess\xf5es maratona.",research:"A evid\xeancia \xe9 mais forte para exatamente o que se esperaria \u2014 com a pr\xe1tica voc\xea fica mensuravelmente mais r\xe1pido e mais preciso nas pr\xf3prias tarefas de rea\xe7\xe3o de escolha, e a rela\xe7\xe3o de Hick-Hyman entre n\xfamero de escolhas e velocidade \xe9 um dos achados mais robustos da psicologia. Afirma\xe7\xf5es de que esse tipo de treino se transfere para a intelig\xeancia geral ou para uma agudeza mental ampla s\xe3o fracas: grandes revis\xf5es de treino cerebral encontram pouca transfer\xeancia distante confi\xe1vel. Um treino mais restrito de velocidade de processamento foi associado, em alguns ensaios, a benef\xedcios cotidianos como dirigir e menor risco de dem\xeancia, mas esses resultados s\xe3o contestados e n\xe3o se generalizam para um simples jogo de rea\xe7\xe3o de escolha, ent\xe3o trate as promessas grandiosas com cautela.",rec:"Busque primeiro uma taxa de erro baixa; deixe os milissegundos ca\xedrem sozinhos depois que sua precis\xe3o estiver est\xe1vel.",faq:[["Qual a diferen\xe7a entre isto e um teste de rea\xe7\xe3o simples?","Um teste simples mede o qu\xe3o r\xe1pido voc\xea reage a um \xfanico sinal conhecido \u2014 voc\xea n\xe3o precisa escolher. Aqui v\xe1rios sinais s\xe3o poss\xedveis e voc\xea precisa selecionar a resposta correspondente, ent\xe3o ele capta o tempo de decis\xe3o por cima do reflexo puro."],["Por que eu fico mais lento quando h\xe1 mais bot\xf5es?","\xc9 a lei de Hick-Hyman em a\xe7\xe3o: cada op\xe7\xe3o extra acrescenta um incremento mais ou menos fixo de tempo de decis\xe3o, ent\xe3o o tempo de rea\xe7\xe3o sobe de modo ordenado e quase logar\xedtmico conforme as escolhas aumentam. \xc9 normal, n\xe3o um sinal de que voc\xea est\xe1 indo mal."],["Isto vai me deixar mais inteligente ou mais \xe1gil no dia a dia?","Vai confiavelmente deix\xe1-lo melhor nesta tarefa e em tarefas de rea\xe7\xe3o semelhantes. A transfer\xeancia ampla para a intelig\xeancia geral ou para a vida cotidiana n\xe3o tem bom respaldo nas evid\xeancias, ent\xe3o aproveite como pr\xe1tica de velocidade direcionada, e n\xe3o como uma melhoria do c\xe9rebro."]],variants:"Variantes comuns mudam o que voc\xea precisa discriminar: cores, formas, setas direcionais, posi\xe7\xe3o esquerda-versus-direita ou mapeamento de teclas com as duas m\xe3os. Modos mais dif\xedceis acrescentam mais escolhas, encurtam a janela de tempo ou inserem sinais de no-go diante dos quais voc\xea precisa conter a resposta, misturando rea\xe7\xe3o de escolha com inibi\xe7\xe3o."},hi:{about:"Choice RT: Speed \u090f\u0915 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0915\u0938\u0930\u0924 \u0939\u0948 \u091c\u093f\u0938\u092e\u0947\u0902 \u090f\u0915 \u0938\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0938\u0902\u092d\u0935 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e\u090f\u0901 \u0939\u094b\u0924\u0940 \u0939\u0948\u0902\u0964 \u090f\u0915 \u0938\u0902\u0915\u0947\u0924 \u092a\u094d\u0930\u0915\u091f \u0939\u094b\u0924\u093e \u0939\u0948 \u2014 \u0915\u094b\u0908 \u0930\u0902\u0917, \u0915\u094b\u0908 \u0924\u0940\u0930, \u0938\u094d\u0915\u094d\u0930\u0940\u0928 \u0915\u093e \u0915\u094b\u0908 \u0915\u093f\u0928\u093e\u0930\u093e \u2014 \u0914\u0930 \u0906\u092a\u0915\u094b \u092c\u093f\u0928\u093e \u0905\u0902\u0926\u093e\u091c\u093c\u093e \u0932\u0917\u093e\u090f \u091c\u093f\u0924\u0928\u0940 \u091c\u0932\u094d\u0926\u0940 \u0939\u094b \u0938\u0915\u0947 \u092e\u0947\u0932 \u0916\u093e\u0924\u093e \u092c\u091f\u0928 \u091a\u0941\u0928\u0928\u093e \u0939\u094b\u0924\u093e \u0939\u0948\u0964 \u0938\u0930\u0932 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u092a\u0930\u0940\u0915\u094d\u0937\u0923 \u0915\u0947 \u0909\u0932\u091f, \u091c\u0939\u093e\u0901 \u0906\u092a \u092c\u0938 \u0915\u093f\u0938\u0940 \u092d\u0940 \u0938\u0902\u0915\u0947\u0924 \u092a\u0930 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0915\u0930\u0924\u0947 \u0939\u0948\u0902, \u092f\u0939\u093e\u0901 \u0906\u092a\u0915\u094b \u092a\u0939\u0932\u0947 \u0924\u092f \u0915\u0930\u0928\u093e \u092a\u0921\u093c\u0924\u093e \u0939\u0948 \u0915\u093f \u092f\u0939 \u0915\u094c\u0928-\u0938\u093e \u0938\u0902\u0915\u0947\u0924 \u0939\u0948, \u0914\u0930 \u0920\u0940\u0915 \u0909\u0938\u0940 \u092b\u093c\u0948\u0938\u0932\u0947 \u0915\u093e \u0906\u092a \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0930 \u0930\u0939\u0947 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902\u0964",benefit:"\u092f\u0939 \u091a\u092f\u0928-\u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0938\u092e\u092f \u0915\u094b \u0927\u093e\u0930 \u0926\u0947\u0924\u093e \u0939\u0948: \u0915\u093f\u0938\u0940 \u0909\u0926\u094d\u0926\u0940\u092a\u0928 \u0915\u094b \u092d\u093e\u0901\u092a\u0928\u0947, \u0909\u0938\u0915\u093e \u092e\u0924\u0932\u092c \u0924\u092f \u0915\u0930\u0928\u0947, \u0914\u0930 \u0938\u0939\u0940 \u0936\u093e\u0930\u0940\u0930\u093f\u0915 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0926\u093e\u0917\u0928\u0947 \u0915\u0940 \u0917\u0924\u093f\u0964 \u0938\u0940\u0927\u0947 \u0936\u092c\u094d\u0926\u094b\u0902 \u092e\u0947\u0902 \u092f\u0939 \u0924\u092f-\u0915\u0930\u094b-\u092b\u093f\u0930-\u0915\u0926\u092e-\u0909\u0920\u093e\u0913 \u0935\u093e\u0932\u0947 \u091a\u0915\u094d\u0930 \u0915\u093e \u0914\u0930 \u0906\u0935\u0947\u0917\u0935\u0936 \u0917\u093c\u0932\u0924 \u091f\u0948\u092a \u0915\u0947 \u092a\u094d\u0930\u0924\u093f \u0906\u092a\u0915\u0947 \u092a\u094d\u0930\u0924\u093f\u0930\u094b\u0927 \u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0930\u093e\u0924\u093e \u0939\u0948, \u0938\u093f\u0930\u094d\u092b\u093c \u0915\u094b\u0930\u0947 \u092a\u094d\u0930\u0924\u093f\u0935\u0930\u094d\u0924 (\u0930\u093f\u092b\u093c\u094d\u0932\u0947\u0915\u094d\u0938) \u0915\u093e \u0928\u0939\u0940\u0902\u0964",history:"\u091a\u092f\u0928-\u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0915\u093e\u0930\u094d\u092f \u092a\u094d\u0930\u093e\u092f\u094b\u0917\u093f\u0915 \u092e\u0928\u094b\u0935\u093f\u091c\u094d\u091e\u093e\u0928 \u0915\u0947 \u091c\u0928\u094d\u092e \u0924\u0915 \u091c\u093e\u0924\u093e \u0939\u0948\u0964 \u0921\u091a \u0936\u0930\u0940\u0930-\u0915\u094d\u0930\u093f\u092f\u093e-\u0935\u093f\u091c\u094d\u091e\u093e\u0928\u0940 F. C. Donders \u0928\u0947 \u0907\u0938\u0947 1868 \u092e\u0947\u0902 \u092e\u093e\u0928\u0938\u093f\u0915 \u0918\u091f\u0928\u093e\u0913\u0902 \u0915\u093e \u0938\u092e\u092f \u0928\u093e\u092a\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u092e\u093e\u092a\u093e, \u0914\u0930 1950 \u0915\u0947 \u0926\u0936\u0915 \u092e\u0947\u0902 \u092f\u0939 \u0915\u093e\u0930\u094d\u092f \u0938\u0942\u091a\u0928\u093e-\u092a\u094d\u0930\u0938\u0902\u0938\u094d\u0915\u0930\u0923 (\u0907\u0928\u094d\u092b\u093c\u0949\u0930\u094d\u092e\u0947\u0936\u0928-\u092a\u094d\u0930\u094b\u0938\u0947\u0938\u093f\u0902\u0917) \u092e\u0928\u094b\u0935\u093f\u091c\u094d\u091e\u093e\u0928 \u0915\u0947 \u0915\u0947\u0902\u0926\u094d\u0930 \u092e\u0947\u0902 \u0906 \u0917\u092f\u093e, \u091c\u092c \u0936\u094b\u0927\u0915\u0930\u094d\u0924\u093e\u0913\u0902 \u0928\u0947 \u0926\u093f\u0916\u093e\u092f\u093e \u0915\u093f \u091c\u0948\u0938\u0947-\u091c\u0948\u0938\u0947 \u0906\u092a \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0935\u093f\u0915\u0932\u094d\u092a \u091c\u094b\u0921\u093c\u0924\u0947 \u0939\u0948\u0902, \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0938\u092e\u092f \u090f\u0915 \u0935\u094d\u092f\u0935\u0938\u094d\u0925\u093f\u0924 \u0922\u0902\u0917 \u0938\u0947 \u092c\u0922\u093c\u0924\u093e \u0939\u0948\u0964",creator:"\u0906\u0927\u0941\u0928\u093f\u0915 \u0910\u092a-\u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0915\u093e \u0915\u094b\u0908 \u090f\u0915\u092e\u093e\u0924\u094d\u0930 \u0906\u0935\u093f\u0937\u094d\u0915\u093e\u0930\u0915 \u0928\u0939\u0940\u0902 \u0939\u0948; \u092f\u0939 Donders \u0915\u0947 1868 \u0915\u0947 \u091a\u092f\u0928-\u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u092a\u094d\u0930\u092f\u094b\u0917 \u0915\u0940 \u0938\u0940\u0927\u0940 \u0938\u0902\u0924\u093e\u0928 \u0939\u0948\u0964 \u092e\u0942\u0932 \u0938\u093f\u0926\u094d\u0927\u093e\u0902\u0924 \u2014 \u0915\u093f \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0938\u092e\u092f \u0935\u093f\u0915\u0932\u094d\u092a\u094b\u0902 \u0915\u0940 \u0938\u0902\u0916\u094d\u092f\u093e \u0915\u0947 \u0938\u093e\u0925 \u0932\u0918\u0941\u0917\u0923\u0915\u0940\u092f (\u0932\u0949\u0917\u0930\u093f\u0926\u094d\u092e\u093f\u0915) \u0930\u0942\u092a \u0938\u0947 \u092c\u0922\u093c\u0924\u093e \u0939\u0948 \u2014 \u092f\u0939\u0940 Hick-Hyman \u0928\u093f\u092f\u092e \u0939\u0948, \u091c\u093f\u0938\u0915\u093e \u0928\u093e\u092e W. E. Hick (1952) \u0914\u0930 Ray Hyman (1953) \u092a\u0930 \u092a\u0921\u093c\u093e, \u091c\u093f\u0928\u094d\u0939\u094b\u0902\u0928\u0947 \u0907\u0938\u0947 \u0938\u094d\u0935\u0924\u0902\u0924\u094d\u0930 \u0930\u0942\u092a \u0938\u0947 \u0938\u094d\u0925\u093e\u092a\u093f\u0924 \u0915\u093f\u092f\u093e\u0964",methods:"\u092a\u0939\u0932\u0947 \u0938\u091f\u0940\u0915\u0924\u093e \u0915\u094b \u0924\u0930\u091c\u0940\u0939 \u0926\u0940\u091c\u093f\u090f, \u092b\u093f\u0930 \u0917\u0924\u093f \u0915\u094b \u2014 \u090f\u0915 \u0924\u0947\u091c\u093c \u0917\u093c\u0932\u0924 \u091c\u0935\u093e\u092c \u090f\u0915 \u091c\u093c\u0930\u093e \u0927\u0940\u092e\u0947 \u0938\u0939\u0940 \u091c\u0935\u093e\u092c \u0938\u0947 \u092c\u0926\u0924\u0930 \u0939\u0948\u0964 \u0905\u092a\u0928\u0940 \u0909\u0901\u0917\u0932\u093f\u092f\u093e\u0901 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0915\u0941\u0902\u091c\u093f\u092f\u094b\u0902 \u092a\u0930 \u091f\u093f\u0915\u093e\u090f \u0930\u0916\u093f\u090f, \u0905\u092a\u0928\u0940 \u0906\u0901\u0916\u0947\u0902 \u0915\u0947\u0902\u0926\u094d\u0930 \u092a\u0930 \u091c\u092e\u093e\u0907\u090f \u091c\u0939\u093e\u0901 \u0938\u0902\u0915\u0947\u0924 \u092a\u094d\u0930\u0915\u091f \u0939\u094b\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u092a\u0942\u0930\u094d\u0935\u093e\u0928\u0941\u092e\u093e\u0928 \u0932\u0917\u093e\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0915\u0940\u091c\u093f\u090f\u0964 \u0915\u093f\u0938\u0940 \u0928\u093f\u091c\u0940 \u0938\u0930\u094d\u0935\u0936\u094d\u0930\u0947\u0937\u094d\u0920 \u0915\u093e \u092a\u0940\u091b\u093e \u0915\u0930\u0928\u0947 \u0938\u0947 \u092a\u0939\u0932\u0947 \u0915\u0941\u091b \u0926\u094c\u0930 \u0935\u093e\u0930\u094d\u092e-\u0905\u092a \u0915\u0940\u091c\u093f\u090f, \u0914\u0930 \u0938\u093f\u0930\u094d\u092b\u093c \u092e\u093f\u0932\u0940\u0938\u0947\u0915\u0902\u0921 \u0915\u0947 \u0906\u0901\u0915\u0921\u093c\u0947 \u0915\u094b \u0928\u0939\u0940\u0902, \u092c\u0932\u094d\u0915\u093f \u0905\u092a\u0928\u0940 \u0924\u094d\u0930\u0941\u091f\u093f-\u0926\u0930 \u0915\u094b \u0926\u0947\u0916\u093f\u090f\u0964",duration:"\u091b\u094b\u091f\u093e \u0914\u0930 \u092c\u093e\u0930-\u092c\u093e\u0930, \u0932\u0902\u092c\u0947 \u0914\u0930 \u0915\u092d\u0940-\u0915\u092d\u093e\u0930 \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u0939\u0948\u0964 \u0930\u094b\u091c\u093c \u0924\u0940\u0928 \u0938\u0947 \u092a\u093e\u0901\u091a \u092e\u093f\u0928\u091f, \u092f\u093e 30 \u0938\u0947 60 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e\u0913\u0902 \u0915\u0947 \u0915\u0941\u091b \u0916\u0902\u0921, \u0915\u093e\u092b\u093c\u0940 \u0939\u0948\u0902; \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0917\u0924\u093f \u091c\u0932\u094d\u0926\u0940 \u092a\u0920\u093e\u0930 (\u092a\u094d\u0932\u0947\u091f\u094b) \u092a\u0930 \u092a\u0939\u0941\u0901\u091a \u091c\u093e\u0924\u0940 \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u092e\u0948\u0930\u093e\u0925\u0928 \u0938\u0924\u094d\u0930\u094b\u0902 \u0938\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0930\u094b\u091c\u093c \u0915\u0940 \u0928\u093f\u0930\u0902\u0924\u0930\u0924\u093e \u092e\u093e\u092f\u0928\u0947 \u0930\u0916\u0924\u0940 \u0939\u0948\u0964",research:"\u0938\u092c\u0938\u0947 \u092a\u0941\u0916\u093c\u094d\u0924\u093e \u0938\u092c\u0942\u0924 \u0920\u0940\u0915 \u0909\u0938\u0940 \u092c\u093e\u0924 \u0915\u093e \u0939\u0948 \u091c\u093f\u0938\u0915\u0940 \u0906\u092a \u0909\u092e\u094d\u092e\u0940\u0926 \u0915\u0930\u0947\u0902\u0917\u0947 \u2014 \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0947 \u0938\u093e\u0925 \u0906\u092a \u0916\u0941\u0926 \u091a\u092f\u0928-\u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0915\u093e\u0930\u094d\u092f\u094b\u0902 \u092e\u0947\u0902 \u0928\u093e\u092a-\u0924\u094c\u0932\u0915\u0930 \u0924\u0947\u091c\u093c \u0935 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0938\u091f\u0940\u0915 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u0935\u093f\u0915\u0932\u094d\u092a\u094b\u0902 \u0924\u0925\u093e \u0917\u0924\u093f \u0915\u0947 \u092c\u0940\u091a \u0915\u093e Hick-Hyman \u0938\u0902\u092c\u0902\u0927 \u092e\u0928\u094b\u0935\u093f\u091c\u094d\u091e\u093e\u0928 \u0915\u0947 \u0938\u092c\u0938\u0947 \u092e\u091c\u093c\u092c\u0942\u0924 \u0928\u0924\u0940\u091c\u094b\u0902 \u092e\u0947\u0902 \u0938\u0947 \u090f\u0915 \u0939\u0948\u0964 \u092f\u0939 \u0926\u093e\u0935\u093e \u0915\u093f \u0907\u0938 \u0924\u0930\u0939 \u0915\u093e \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u0906\u092e \u092c\u0941\u0926\u094d\u0927\u093f \u092f\u093e \u0935\u094d\u092f\u093e\u092a\u0915 \u092e\u093e\u0928\u0938\u093f\u0915 \u0924\u0940\u0915\u094d\u0937\u094d\u0923\u0924\u093e \u0924\u0915 \u0939\u0938\u094d\u0924\u093e\u0902\u0924\u0930\u093f\u0924 \u0939\u094b\u0924\u093e \u0939\u0948 \u2014 \u0915\u092e\u091c\u093c\u094b\u0930 \u0939\u0948: \u0926\u093f\u092e\u093e\u0917\u0940 \u0915\u0938\u0930\u0924 \u0915\u0940 \u092c\u0921\u093c\u0940 \u0938\u092e\u0940\u0915\u094d\u0937\u093e\u0913\u0902 \u0915\u094b \u0915\u094b\u0908 \u0916\u093e\u0938 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0926\u0942\u0930-\u0939\u0938\u094d\u0924\u093e\u0902\u0924\u0930\u0923 \u0928\u0939\u0940\u0902 \u092e\u093f\u0932\u0924\u093e\u0964 \u0915\u0941\u091b \u092a\u0930\u0940\u0915\u094d\u0937\u0923\u094b\u0902 \u092e\u0947\u0902 \u0938\u0902\u0915\u0930\u0947 \u092a\u094d\u0930\u0938\u0902\u0938\u094d\u0915\u0930\u0923-\u0917\u0924\u093f \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u0915\u094b \u0921\u094d\u0930\u093e\u0907\u0935\u093f\u0902\u0917 \u0914\u0930 \u0915\u092e \u092e\u0928\u094b\u092d\u094d\u0930\u0902\u0936 (\u0921\u093f\u092e\u0947\u0902\u0936\u093f\u092f\u093e) \u091c\u094b\u0916\u093f\u092e \u091c\u0948\u0938\u0947 \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0947 \u092b\u093c\u093e\u092f\u0926\u094b\u0902 \u0938\u0947 \u091c\u094b\u0921\u093c\u093e \u0917\u092f\u093e \u0939\u0948, \u092e\u0917\u0930 \u0935\u0947 \u0928\u0924\u0940\u091c\u0947 \u0935\u093f\u0935\u093e\u0926\u093f\u0924 \u0939\u0948\u0902 \u0914\u0930 \u0915\u093f\u0938\u0940 \u0938\u093e\u0926\u0947 \u091a\u092f\u0928-\u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0917\u0947\u092e \u0924\u0915 \u0938\u093e\u092e\u093e\u0928\u094d\u092f\u0940\u0915\u0943\u0924 \u0928\u0939\u0940\u0902 \u0939\u094b\u0924\u0947, \u0907\u0938\u0932\u093f\u090f \u092c\u0921\u093c\u0947 \u0935\u093e\u0926\u094b\u0902 \u0915\u094b \u0938\u093e\u0935\u0927\u093e\u0928\u0940 \u0938\u0947 \u0932\u0940\u091c\u093f\u090f\u0964",rec:"\u092a\u0939\u0932\u0947 \u0915\u092e \u0924\u094d\u0930\u0941\u091f\u093f-\u0926\u0930 \u0915\u093e \u092a\u0940\u091b\u093e \u0915\u0940\u091c\u093f\u090f; \u091c\u092c \u0906\u092a\u0915\u0940 \u0938\u091f\u0940\u0915\u0924\u093e \u0938\u094d\u0925\u093f\u0930 \u0939\u094b \u091c\u093e\u090f \u0924\u094b \u092e\u093f\u0932\u0940\u0938\u0947\u0915\u0902\u0921 \u0915\u094b \u0905\u092a\u0928\u0947-\u0906\u092a \u0917\u093f\u0930\u0928\u0947 \u0926\u0940\u091c\u093f\u090f\u0964",faq:[["\u092f\u0939 \u0938\u0930\u0932 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u092a\u0930\u0940\u0915\u094d\u0937\u0923 \u0938\u0947 \u0915\u0948\u0938\u0947 \u0905\u0932\u0917 \u0939\u0948?","\u090f\u0915 \u0938\u0930\u0932 \u092a\u0930\u0940\u0915\u094d\u0937\u0923 \u0928\u093e\u092a\u0924\u093e \u0939\u0948 \u0915\u093f \u0906\u092a \u090f\u0915 \u0905\u0915\u0947\u0932\u0947 \u091c\u094d\u091e\u093e\u0924 \u0938\u0902\u0915\u0947\u0924 \u092a\u0930 \u0915\u093f\u0924\u0928\u0940 \u0924\u0947\u091c\u093c\u0940 \u0938\u0947 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0915\u0930\u0924\u0947 \u0939\u0948\u0902 \u2014 \u0906\u092a\u0915\u094b \u091a\u0941\u0928\u0928\u093e \u0928\u0939\u0940\u0902 \u092a\u0921\u093c\u0924\u093e\u0964 \u092f\u0939\u093e\u0901 \u0915\u0908 \u0938\u0902\u0915\u0947\u0924 \u092e\u0941\u092e\u0915\u093f\u0928 \u0939\u0948\u0902 \u0914\u0930 \u0906\u092a\u0915\u094b \u092e\u0947\u0932 \u0916\u093e\u0924\u0940 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u091a\u0941\u0928\u0928\u0940 \u092a\u0921\u093c\u0924\u0940 \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u092f\u0939 \u0915\u094b\u0930\u0947 \u092a\u094d\u0930\u0924\u093f\u0935\u0930\u094d\u0924 \u0915\u0947 \u090a\u092a\u0930 \u092b\u093c\u0948\u0938\u0932\u0947 \u0915\u093e \u0938\u092e\u092f \u092d\u0940 \u092a\u0915\u0921\u093c\u0924\u093e \u0939\u0948\u0964"],["\u091c\u092c \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u092c\u091f\u0928 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902 \u0924\u094b \u092e\u0948\u0902 \u0927\u0940\u092e\u093e \u0915\u094d\u092f\u094b\u0902 \u0939\u094b \u091c\u093e\u0924\u093e \u0939\u0942\u0901?","\u092f\u0939\u0940 Hick-Hyman \u0928\u093f\u092f\u092e \u0915\u093e\u092e \u0915\u0930 \u0930\u0939\u093e \u0939\u094b\u0924\u093e \u0939\u0948: \u0939\u0930 \u0905\u0924\u093f\u0930\u093f\u0915\u094d\u0924 \u0935\u093f\u0915\u0932\u094d\u092a \u092b\u093c\u0948\u0938\u0932\u0947 \u0915\u0947 \u0938\u092e\u092f \u092e\u0947\u0902 \u0915\u0930\u0940\u092c-\u0915\u0930\u0940\u092c \u090f\u0915 \u0924\u092f \u092c\u0922\u093c\u094b\u0924\u0930\u0940 \u091c\u094b\u0921\u093c \u0926\u0947\u0924\u093e \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u091c\u0948\u0938\u0947-\u091c\u0948\u0938\u0947 \u0935\u093f\u0915\u0932\u094d\u092a \u092c\u0922\u093c\u0924\u0947 \u0939\u0948\u0902 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0938\u092e\u092f \u090f\u0915 \u0935\u094d\u092f\u0935\u0938\u094d\u0925\u093f\u0924, \u0932\u0917\u092d\u0917-\u0932\u0918\u0941\u0917\u0923\u0915\u0940\u092f \u0922\u0902\u0917 \u0938\u0947 \u091a\u0922\u093c\u0924\u093e \u0939\u0948\u0964 \u092f\u0939 \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u0939\u0948, \u0907\u0938 \u092c\u093e\u0924 \u0915\u0940 \u0928\u093f\u0936\u093e\u0928\u0940 \u0928\u0939\u0940\u0902 \u0915\u093f \u0906\u092a \u092c\u0941\u0930\u093e \u0915\u0930 \u0930\u0939\u0947 \u0939\u0948\u0902\u0964"],["\u0915\u094d\u092f\u093e \u092f\u0939 \u092e\u0941\u091d\u0947 \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0940 \u091c\u093c\u093f\u0902\u0926\u0917\u0940 \u092e\u0947\u0902 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0939\u094b\u0936\u093f\u092f\u093e\u0930 \u092f\u093e \u0924\u0947\u091c\u093c \u092c\u0928\u093e \u0926\u0947\u0917\u093e?","\u092f\u0939 \u0906\u092a\u0915\u094b \u0907\u0938 \u0915\u093e\u0930\u094d\u092f \u0914\u0930 \u092e\u093f\u0932\u0924\u0947-\u091c\u0941\u0932\u0924\u0947 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0915\u093e\u0930\u094d\u092f\u094b\u0902 \u092e\u0947\u0902 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0922\u0902\u0917 \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u092c\u0928\u093e \u0926\u0947\u0917\u093e\u0964 \u0906\u092e \u092c\u0941\u0926\u094d\u0927\u093f \u092f\u093e \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0940 \u091c\u093c\u093f\u0902\u0926\u0917\u0940 \u0924\u0915 \u0935\u094d\u092f\u093e\u092a\u0915 \u0938\u094d\u0925\u093e\u0928\u093e\u0902\u0924\u0930\u0923 \u0915\u094b \u0938\u092c\u0942\u0924\u094b\u0902 \u0915\u093e \u0905\u091a\u094d\u091b\u093e \u0938\u092e\u0930\u094d\u0925\u0928 \u0939\u093e\u0938\u093f\u0932 \u0928\u0939\u0940\u0902 \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0907\u0938\u0947 \u0926\u093f\u092e\u093e\u0917\u0940 \u0905\u092a\u0917\u094d\u0930\u0947\u0921 \u0928\u0939\u0940\u0902, \u092c\u0932\u094d\u0915\u093f \u0928\u093f\u0936\u093e\u0928\u093e-\u092c\u0926\u094d\u0927 \u0917\u0924\u093f-\u0905\u092d\u094d\u092f\u093e\u0938 \u092e\u093e\u0928\u0915\u0930 \u0907\u0938\u0915\u093e \u0906\u0928\u0902\u0926 \u0932\u0940\u091c\u093f\u090f\u0964"]],variants:"\u0906\u092e \u092c\u0926\u0932\u093e\u0935 \u092f\u0939 \u092c\u0926\u0932\u0924\u0947 \u0939\u0948\u0902 \u0915\u093f \u0906\u092a\u0915\u094b \u0915\u093f\u0938 \u091a\u0940\u091c\u093c \u092e\u0947\u0902 \u092d\u0947\u0926 \u0915\u0930\u0928\u093e \u0939\u0948: \u0930\u0902\u0917, \u0906\u0915\u0943\u0924\u093f\u092f\u093e\u0901, \u0926\u093f\u0936\u093e \u0935\u093e\u0932\u0947 \u0924\u0940\u0930, \u092c\u093e\u090f\u0901-\u092c\u0928\u093e\u092e-\u0926\u093e\u090f\u0901 \u0938\u094d\u0925\u093f\u0924\u093f, \u092f\u093e \u0926\u094b-\u0939\u093e\u0925 \u0935\u093e\u0932\u0940 \u0915\u0941\u0902\u091c\u0940-\u092e\u0948\u092a\u093f\u0902\u0917\u0964 \u0915\u0920\u093f\u0928 \u092e\u094b\u0921 \u0914\u0930 \u0935\u093f\u0915\u0932\u094d\u092a \u091c\u094b\u0921\u093c \u0926\u0947\u0924\u0947 \u0939\u0948\u0902, \u0938\u092e\u092f-\u0916\u093f\u0921\u093c\u0915\u0940 \u0938\u093f\u0915\u094b\u0921\u093c \u0926\u0947\u0924\u0947 \u0939\u0948\u0902, \u092f\u093e \u0928\u094b-\u0917\u094b \u0938\u0902\u0915\u0947\u0924 \u0921\u093e\u0932 \u0926\u0947\u0924\u0947 \u0939\u0948\u0902 \u091c\u093f\u0928 \u092a\u0930 \u0906\u092a\u0915\u094b \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0930\u094b\u0915\u0928\u0940 \u0939\u094b\u0924\u0940 \u0939\u0948, \u091c\u093f\u0938\u0938\u0947 \u091a\u092f\u0928-\u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u092e\u0947\u0902 \u0905\u0935\u0930\u094b\u0927\u0928 (\u0907\u0928\u094d\u0939\u093f\u092c\u093f\u0936\u0928) \u0918\u0941\u0932 \u091c\u093e\u0924\u093e \u0939\u0948\u0964"},zh:{about:"\u300a\u9009\u62e9\u53cd\u5e94\uff1a\u901f\u5ea6\u300b\u662f\u4e00\u4e2a\u6709\u4e0d\u6b62\u4e00\u79cd\u53ef\u80fd\u53cd\u5e94\u7684\u53cd\u5e94\u7ec3\u4e60\u3002\u4e00\u4e2a\u4fe1\u53f7\u51fa\u73b0\u2014\u2014\u4e00\u79cd\u989c\u8272\u3001\u4e00\u4e2a\u7bad\u5934\u3001\u5c4f\u5e55\u7684\u67d0\u4e00\u4fa7\u2014\u2014\u4f60\u5fc5\u987b\u4e0d\u9760\u731c\u5730\u4ee5\u6700\u5feb\u901f\u5ea6\u6309\u4e0b\u5bf9\u5e94\u7684\u6309\u94ae\u3002\u548c\u90a3\u79cd\u53ea\u9700\u5bf9\u4efb\u610f\u4fe1\u53f7\u505a\u51fa\u53cd\u5e94\u7684\u7b80\u5355\u53cd\u5e94\u6d4b\u8bd5\u4e0d\u540c\uff0c\u5728\u8fd9\u91cc\u4f60\u5f97\u5148\u5224\u65ad\u5b83\u662f\u54ea\u4e2a\u4fe1\u53f7\uff0c\u800c\u8fd9\u4e2a\u5224\u65ad\u6070\u6070\u5c31\u662f\u4f60\u6240\u8bad\u7ec3\u7684\u4e1c\u897f\u3002",benefit:"\u5b83\u78e8\u5feb\u9009\u62e9\u53cd\u5e94\u65f6\uff1a\u611f\u77e5\u523a\u6fc0\u3001\u5224\u65ad\u5b83\u7684\u542b\u4e49\u3001\u5e76\u542f\u52a8\u6b63\u786e\u8fd0\u52a8\u53cd\u5e94\u7684\u901f\u5ea6\u3002\u8bf4\u767d\u4e86\uff0c\u5b83\u8bad\u7ec3\u7684\u662f\u300e\u5148\u5224\u65ad\u518d\u884c\u52a8\u300f\u7684\u56de\u8def\u4ee5\u53ca\u4f60\u5bf9\u51b2\u52a8\u6027\u9519\u8bef\u70b9\u51fb\u7684\u62b5\u6297\u529b\uff0c\u800c\u4e0d\u4ec5\u4ec5\u662f\u7eaf\u7cb9\u7684\u672c\u80fd\u53cd\u5c04\u3002",history:"\u9009\u62e9\u53cd\u5e94\u4efb\u52a1\u53ef\u4ee5\u8ffd\u6eaf\u5230\u5b9e\u9a8c\u5fc3\u7406\u5b66\u7684\u8bde\u751f\u3002\u8377\u5170\u751f\u7406\u5b66\u5bb6F. C. Donders\u57281868\u5e74\u6d4b\u91cf\u4e86\u5b83\uff0c\u7528\u4ee5\u7ed9\u5fc3\u7406\u4e8b\u4ef6\u8ba1\u65f6\uff1b\u5230\u4e8620\u4e16\u7eaa50\u5e74\u4ee3\uff0c\u8fd9\u4e2a\u4efb\u52a1\u6210\u4e3a\u4fe1\u606f\u52a0\u5de5\u5fc3\u7406\u5b66\u7684\u6838\u5fc3\uff0c\u5f53\u65f6\u7814\u7a76\u8005\u8bc1\u660e\uff0c\u968f\u7740\u4f60\u589e\u52a0\u66f4\u591a\u7684\u53cd\u5e94\u9009\u9879\uff0c\u53cd\u5e94\u65f6\u4f1a\u4ee5\u4e00\u79cd\u6709\u89c4\u5f8b\u7684\u65b9\u5f0f\u589e\u957f\u3002",creator:"\u73b0\u4ee3\u5e94\u7528\u7248\u672c\u6ca1\u6709\u5355\u4e00\u7684\u53d1\u660e\u8005\uff1b\u5b83\u662fDonders 1868\u5e74\u9009\u62e9\u53cd\u5e94\u5b9e\u9a8c\u7684\u76f4\u7cfb\u540e\u88d4\u3002\u5176\u6838\u5fc3\u539f\u7406\u2014\u2014\u53cd\u5e94\u65f6\u968f\u9009\u62e9\u6570\u91cf\u5448\u5bf9\u6570\u4e0a\u5347\u2014\u2014\u5c31\u662f\u5e0c\u514b-\u6d77\u66fc\u5b9a\u5f8b\uff0c\u4ee5W. E. Hick\uff081952\uff09\u548cRay Hyman\uff081953\uff09\u547d\u540d\uff0c\u4e8c\u4eba\u5404\u81ea\u72ec\u7acb\u786e\u7acb\u4e86\u8fd9\u4e00\u89c4\u5f8b\u3002",methods:"\u5148\u628a\u51c6\u786e\u653e\u5728\u7b2c\u4e00\u4f4d\uff0c\u7136\u540e\u624d\u662f\u901f\u5ea6\u2014\u2014\u4e00\u4e2a\u5feb\u901f\u7684\u9519\u8bef\u7b54\u6848\u6bd4\u4e00\u4e2a\u7565\u6162\u7684\u6b63\u786e\u7b54\u6848\u66f4\u7cdf\u3002\u8ba9\u4f60\u7684\u624b\u6307\u6401\u5728\u53cd\u5e94\u952e\u4e0a\uff0c\u76ee\u5149\u56fa\u5b9a\u5728\u4fe1\u53f7\u51fa\u73b0\u7684\u4e2d\u5fc3\uff0c\u53bb\u53cd\u5e94\u800c\u4e0d\u662f\u53bb\u9884\u6d4b\u3002\u5728\u8ffd\u6c42\u4e2a\u4eba\u6700\u4f73\u6210\u7ee9\u4e4b\u524d\u5148\u70ed\u8eab\u51e0\u8f6e\uff0c\u5e76\u76ef\u7740\u4f60\u7684\u9519\u8bef\u7387\uff0c\u800c\u4e0d\u53ea\u662f\u90a3\u4e2a\u6beb\u79d2\u6570\u5b57\u3002",duration:"\u77ed\u800c\u9891\u7e41\u80dc\u8fc7\u957f\u800c\u7a00\u5c11\u3002\u6bcf\u5929\u4e09\u5230\u4e94\u5206\u949f\uff0c\u6216\u8005\u51e0\u7ec430\u523060\u6b21\u7684\u53cd\u5e94\uff0c\u5c31\u8db3\u591f\u4e86\uff1b\u53cd\u5e94\u901f\u5ea6\u5f88\u5feb\u5c31\u4f1a\u8fdb\u5165\u5e73\u53f0\u671f\uff0c\u6240\u4ee5\u6bcf\u65e5\u7684\u7a33\u5b9a\u575a\u6301\u6bd4\u9a6c\u62c9\u677e\u5f0f\u7684\u7ec3\u4e60\u66f4\u91cd\u8981\u3002",research:"\u8bc1\u636e\u6700\u5f3a\u7684\u6070\u6070\u662f\u4f60\u80fd\u6599\u5230\u7684\u90a3\u90e8\u5206\u2014\u2014\u968f\u7740\u7ec3\u4e60\uff0c\u4f60\u5728\u9009\u62e9\u53cd\u5e94\u4efb\u52a1\u672c\u8eab\u4e0a\u4f1a\u53d8\u5f97\u660e\u663e\u66f4\u5feb\u3001\u66f4\u51c6\uff0c\u800c\u9009\u62e9\u6570\u91cf\u4e0e\u901f\u5ea6\u4e4b\u95f4\u7684\u5e0c\u514b-\u6d77\u66fc\u5173\u7cfb\u662f\u5fc3\u7406\u5b66\u4e2d\u6700\u7a33\u5065\u7684\u53d1\u73b0\u4e4b\u4e00\u3002\u81f3\u4e8e\u8fd9\u7c7b\u8bad\u7ec3\u80fd\u8fc1\u79fb\u5230\u4e00\u822c\u667a\u529b\u6216\u5e7f\u6cdb\u7684\u5fc3\u667a\u654f\u9510\u5ea6\u7684\u8bf4\u6cd5\u5219\u5f88\u8584\u5f31\uff1a\u5bf9\u5065\u8111\u8bad\u7ec3\u7684\u5927\u578b\u7efc\u8ff0\u53d1\u73b0\u51e0\u4e4e\u6ca1\u6709\u53ef\u9760\u7684\u8fdc\u8fc1\u79fb\u3002\u8303\u56f4\u66f4\u7a84\u7684\u52a0\u5de5\u901f\u5ea6\u8bad\u7ec3\u5728\u67d0\u4e9b\u8bd5\u9a8c\u4e2d\u88ab\u5173\u8054\u5230\u8bf8\u5982\u5f00\u8f66\u548c\u964d\u4f4e\u75f4\u5446\u98ce\u9669\u8fd9\u6837\u7684\u65e5\u5e38\u76ca\u5904\uff0c\u4f46\u90a3\u4e9b\u7ed3\u679c\u6709\u4e89\u8bae\uff0c\u4e14\u65e0\u6cd5\u63a8\u5e7f\u5230\u4e00\u4e2a\u6734\u7d20\u7684\u9009\u62e9\u53cd\u5e94\u6e38\u620f\u4e0a\uff0c\u6240\u4ee5\u5bf9\u5b8f\u5927\u7684\u627f\u8bfa\u8981\u4fdd\u6301\u8c28\u614e\u3002",rec:"\u5148\u8ffd\u6c42\u4f4e\u9519\u8bef\u7387\uff1b\u7b49\u4f60\u7684\u51c6\u786e\u7387\u7a33\u5b9a\u4e0b\u6765\u540e\uff0c\u8ba9\u6beb\u79d2\u6570\u81ea\u884c\u4e0b\u964d\u3002",faq:[["\u8fd9\u548c\u7b80\u5355\u53cd\u5e94\u6d4b\u8bd5\u6709\u4ec0\u4e48\u533a\u522b\uff1f","\u7b80\u5355\u6d4b\u8bd5\u8861\u91cf\u7684\u662f\u4f60\u5bf9\u5355\u4e00\u5df2\u77e5\u4fe1\u53f7\u53cd\u5e94\u6709\u591a\u5feb\u2014\u2014\u4f60\u4e0d\u9700\u8981\u505a\u9009\u62e9\u3002\u800c\u5728\u8fd9\u91cc\u6709\u51e0\u4e2a\u53ef\u80fd\u7684\u4fe1\u53f7\uff0c\u4f60\u5fc5\u987b\u9009\u51fa\u5bf9\u5e94\u7684\u53cd\u5e94\uff0c\u6240\u4ee5\u5b83\u5728\u7eaf\u7cb9\u53cd\u5c04\u4e4b\u4e0a\u8fd8\u6355\u6349\u5230\u4e86\u5224\u65ad\u7684\u65f6\u95f4\u3002"],["\u4e3a\u4ec0\u4e48\u6309\u94ae\u8d8a\u591a\u6211\u5c31\u8d8a\u6162\uff1f","\u8fd9\u5c31\u662f\u5e0c\u514b-\u6d77\u66fc\u5b9a\u5f8b\u5728\u8d77\u4f5c\u7528\uff1a\u6bcf\u591a\u4e00\u4e2a\u9009\u9879\u5c31\u589e\u52a0\u5927\u81f4\u56fa\u5b9a\u7684\u4e00\u6bb5\u5224\u65ad\u65f6\u95f4\uff0c\u6240\u4ee5\u968f\u7740\u9009\u62e9\u589e\u591a\uff0c\u53cd\u5e94\u65f6\u4f1a\u4ee5\u4e00\u79cd\u6709\u89c4\u5f8b\u7684\u3001\u8fd1\u4e4e\u5bf9\u6570\u7684\u65b9\u5f0f\u6500\u5347\u3002\u8fd9\u5f88\u6b63\u5e38\uff0c\u5e76\u4e0d\u662f\u4f60\u8868\u73b0\u4e0d\u597d\u7684\u8ff9\u8c61\u3002"],["\u8fd9\u4f1a\u8ba9\u6211\u66f4\u806a\u660e\uff0c\u6216\u5728\u65e5\u5e38\u751f\u6d3b\u4e2d\u66f4\u654f\u6377\u5417\uff1f","\u5b83\u4e00\u5b9a\u4f1a\u8ba9\u4f60\u5728\u8fd9\u4e2a\u4efb\u52a1\u4ee5\u53ca\u7c7b\u4f3c\u7684\u53cd\u5e94\u4efb\u52a1\u4e0a\u505a\u5f97\u66f4\u597d\u3002\u81f3\u4e8e\u80fd\u5426\u5e7f\u6cdb\u5ef6\u7eed\u5230\u4e00\u822c\u667a\u529b\u6216\u65e5\u5e38\u751f\u6d3b\uff0c\u8bc1\u636e\u5e76\u672a\u5145\u5206\u652f\u6301\uff0c\u6240\u4ee5\u628a\u5b83\u5f53\u4f5c\u9488\u5bf9\u6027\u7684\u901f\u5ea6\u7ec3\u4e60\u6765\u4eab\u53d7\uff0c\u800c\u4e0d\u662f\u4e00\u6b21\u5927\u8111\u5347\u7ea7\u3002"]],variants:"\u5e38\u89c1\u7684\u53d8\u4f53\u4f1a\u6539\u53d8\u4f60\u5fc5\u987b\u8fa8\u522b\u7684\u5bf9\u8c61\uff1a\u989c\u8272\u3001\u5f62\u72b6\u3001\u65b9\u5411\u7bad\u5934\u3001\u5de6\u5bf9\u53f3\u7684\u4f4d\u7f6e\uff0c\u6216\u8005\u53cc\u624b\u952e\u4f4d\u6620\u5c04\u3002\u66f4\u96be\u7684\u6a21\u5f0f\u4f1a\u589e\u52a0\u9009\u9879\u6570\u91cf\u3001\u538b\u7f29\u65f6\u95f4\u7a97\u53e3\uff0c\u6216\u8005\u63ba\u5165\u4f60\u5fc5\u987b\u514b\u5236\u53cd\u5e94\u7684no-go\u4fe1\u53f7\uff0c\u628a\u9009\u62e9\u53cd\u5e94\u4e0e\u6291\u5236\u80fd\u529b\u878d\u5408\u5728\u4e00\u8d77\u3002"}},corsi:{ru:{about:"\u041d\u0430\u0431\u043e\u0440 \u0431\u043b\u043e\u043a\u043e\u0432 \u0437\u0430\u0433\u043e\u0440\u0430\u0435\u0442\u0441\u044f \u0432 \u043e\u043f\u0440\u0435\u0434\u0435\u043b\u0451\u043d\u043d\u043e\u0439 \u043f\u043e\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u0438; \u0442\u044b \u043f\u043e\u0432\u0442\u043e\u0440\u044f\u0435\u0448\u044c \u0435\u0451 \u0442\u0435\u043c \u0436\u0435 \u043f\u043e\u0440\u044f\u0434\u043a\u043e\u043c. \u0426\u0435\u043f\u043e\u0447\u043a\u0430 \u0440\u0430\u0441\u0442\u0451\u0442, \u043f\u043e\u043a\u0430 \u043d\u0435 \u043f\u0435\u0440\u0435\u0441\u0442\u0430\u0451\u0448\u044c \u0435\u0451 \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0438\u0442\u044c \u2014 \u044d\u0442\u0430 \u0434\u043b\u0438\u043d\u0430 \u0438 \u0435\u0441\u0442\u044c \u0442\u0432\u043e\u0439 \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0439 \u043e\u0431\u044a\u0451\u043c.",benefit:"\u0417\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u043e-\u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u0443\u044e \u043a\u0440\u0430\u0442\u043a\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u0443\u044e \u0438 \u0440\u0430\u0431\u043e\u0447\u0443\u044e \u043f\u0430\u043c\u044f\u0442\u044c \u2014 \u0443\u0434\u0435\u0440\u0436\u0430\u043d\u0438\u0435 \u0438 \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u0435\u0434\u0435\u043d\u0438\u0435 \u043d\u0430\u0431\u043e\u0440\u0430 \u043f\u043e\u0437\u0438\u0446\u0438\u0439 \u043f\u043e \u043f\u043e\u0440\u044f\u0434\u043a\u0443, \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0439 \u0430\u043d\u0430\u043b\u043e\u0433 \u043e\u0431\u044a\u0451\u043c\u0430 \u0446\u0438\u0444\u0440.",history:"\u0421 \u043d\u0430\u0447\u0430\u043b\u0430 1970-\u0445 \u2014 \u043e\u0434\u0438\u043d \u0438\u0437 \u0441\u0442\u0430\u043d\u0434\u0430\u0440\u0442\u043d\u044b\u0445 \u043d\u0435\u0439\u0440\u043e\u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u0438\u0445 \u0442\u0435\u0441\u0442\u043e\u0432 \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0439 \u043f\u0430\u043c\u044f\u0442\u0438; \u043f\u0440\u0438\u043c\u0435\u043d\u044f\u0435\u0442\u0441\u044f \u0432 \u043a\u043b\u0438\u043d\u0438\u043a\u0435 \u0438 \u0442\u044b\u0441\u044f\u0447\u0430\u0445 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u0439, \u043f\u043e\u0442\u043e\u043c\u0443 \u0447\u0442\u043e \u043f\u043e\u0447\u0442\u0438 \u043d\u0435 \u0442\u0440\u0435\u0431\u0443\u0435\u0442 \u044f\u0437\u044b\u043a\u0430.",creator:"\u041a\u0430\u043d\u0430\u0434\u0441\u043a\u043e-\u0438\u0442\u0430\u043b\u044c\u044f\u043d\u0441\u043a\u0438\u0439 \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433 \u0424\u0438\u043b\u0438\u043f \u041a\u043e\u0440\u0441\u0438 \u2014 \u0440\u0430\u0437\u0440\u0430\u0431\u043e\u0442\u0430\u043b \u0442\u0435\u0441\u0442 \u0432 \u043d\u0430\u0447\u0430\u043b\u0435 1970-\u0445 (1971\u201372), \u0440\u0430\u0431\u043e\u0442\u0430\u044f \u0441 \u0411\u0440\u0435\u043d\u0434\u043e\u0439 \u041c\u0438\u043b\u043d\u0435\u0440 \u0432 \u0423\u043d\u0438\u0432\u0435\u0440\u0441\u0438\u0442\u0435\u0442\u0435 \u041c\u0430\u043a\u0433\u0438\u043b\u043b\u0430.",methods:"\u0414\u043e\u0441\u043c\u043e\u0442\u0440\u0438 \u0432\u0441\u044e \u043f\u043e\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c \u0434\u043e \u043a\u043e\u043d\u0446\u0430, \u043f\u0440\u0435\u0436\u0434\u0435 \u0447\u0435\u043c \u043d\u0430\u0436\u0438\u043c\u0430\u0442\u044c; \u043d\u0435 \u0434\u0432\u0438\u0433\u0430\u0439\u0441\u044f, \u043f\u043e\u043a\u0430 \u043d\u0435 \u0437\u0430\u043a\u043e\u043d\u0447\u0438\u043b\u0430\u0441\u044c. \u0414\u043b\u0438\u043d\u043d\u044b\u0435 \u0446\u0435\u043f\u043e\u0447\u043a\u0438 \u0433\u0440\u0443\u043f\u043f\u0438\u0440\u0443\u0439 \u0432 \u0444\u0438\u0433\u0443\u0440\u044b \u0438\u043b\u0438 \u043c\u0430\u0440\u0448\u0440\u0443\u0442\u044b. \u0414\u043e\u0432\u043e\u0434\u0438 \u0434\u043e \u0434\u043b\u0438\u043d\u044b, \u0433\u0434\u0435 \u043e\u0448\u0438\u0431\u0430\u0435\u0448\u044c\u0441\u044f \u043f\u0440\u0438\u043c\u0435\u0440\u043d\u043e \u0432 \u043f\u043e\u043b\u043e\u0432\u0438\u043d\u0435 \u0441\u043b\u0443\u0447\u0430\u0435\u0432 \u2014 \u043d\u0430 \u044d\u0442\u043e\u0439 \u0433\u0440\u0430\u043d\u0438 \u043e\u0431\u044a\u0451\u043c \u0440\u0430\u0441\u0442\u0451\u0442.",duration:"\u041a\u043e\u0440\u043e\u0442\u043a\u0438\u0435 \u0435\u0436\u0435\u0434\u043d\u0435\u0432\u043d\u044b\u0435 \u0441\u0435\u0441\u0441\u0438\u0438 \u043f\u043e \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u043c\u0438\u043d\u0443\u0442. \u041f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0439 \u043e\u0431\u044a\u0451\u043c \u0434\u043e\u0432\u043e\u043b\u044c\u043d\u043e \u0441\u0442\u0430\u0431\u0438\u043b\u0435\u043d, \u0442\u0430\u043a \u0447\u0442\u043e \u0436\u0434\u0438 \u0443\u043c\u0435\u0440\u0435\u043d\u043d\u043e\u0433\u043e \u043f\u043e\u0441\u0442\u0435\u043f\u0435\u043d\u043d\u043e\u0433\u043e \u0440\u043e\u0441\u0442\u0430, \u0430 \u043d\u0435 \u0440\u0435\u0437\u043a\u0438\u0445 \u0441\u043a\u0430\u0447\u043a\u043e\u0432.",research:"\u0425\u043e\u0440\u043e\u0448\u043e \u0432\u0430\u043b\u0438\u0434\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u0430\u044f \u043c\u0435\u0440\u0430 \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0433\u043e \u043e\u0431\u044a\u0451\u043c\u0430; \u0441\u0440\u0435\u0434\u043d\u0438\u0439 \u0437\u0434\u043e\u0440\u043e\u0432\u044b\u0439 \u0432\u0437\u0440\u043e\u0441\u043b\u044b\u0439 \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0438\u0442 \u043e\u043a\u043e\u043b\u043e \u043f\u044f\u0442\u0438 \u0431\u043b\u043e\u043a\u043e\u0432. \u041f\u0440\u0430\u043a\u0442\u0438\u043a\u0430 \u043f\u043e\u0432\u044b\u0448\u0430\u0435\u0442 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442 \u0432 \u0437\u0430\u0434\u0430\u0447\u0435, \u043d\u043e, \u043a\u0430\u043a \u0443 \u043b\u044e\u0431\u043e\u0439 \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0438 \u043e\u0431\u044a\u0451\u043c\u0430, \u0448\u0438\u0440\u043e\u043a\u0438\u0439 \u043f\u0435\u0440\u0435\u043d\u043e\u0441 \u043d\u0430 \u043d\u0435\u0441\u0432\u044f\u0437\u0430\u043d\u043d\u044b\u0435 \u0441\u043f\u043e\u0441\u043e\u0431\u043d\u043e\u0441\u0442\u0438 \u043e\u0433\u0440\u0430\u043d\u0438\u0447\u0435\u043d.",rec:"\u0418\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0439, \u0447\u0442\u043e\u0431\u044b \u0437\u0430\u043c\u0435\u0440\u044f\u0442\u044c \u0438 \u043c\u044f\u0433\u043a\u043e \u043f\u043e\u0434\u0442\u0430\u043b\u043a\u0438\u0432\u0430\u0442\u044c \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u0443\u044e \u043f\u0430\u043c\u044f\u0442\u044c. \u0421\u0440\u0430\u0432\u043d\u0438\u0432\u0430\u0439 \u043e\u0431\u044a\u0451\u043c \u0441\u043e \u0441\u0432\u043e\u0438\u043c\u0438 \u043f\u0440\u043e\u0448\u043b\u044b\u043c\u0438 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442\u0430\u043c\u0438, \u0430 \u043d\u0435 \u0441 \xab\u043d\u043e\u0440\u043c\u043e\u0439\xbb.",faq:[["\u0427\u0442\u043e \u0442\u0430\u043a\u043e\u0435 \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0439 \u043e\u0431\u044a\u0451\u043c?","\u0421\u0430\u043c\u0430\u044f \u0434\u043b\u0438\u043d\u043d\u0430\u044f \u0446\u0435\u043f\u043e\u0447\u043a\u0430 \u043f\u043e\u0437\u0438\u0446\u0438\u0439, \u043a\u043e\u0442\u043e\u0440\u0443\u044e \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0438\u0448\u044c \u043f\u043e \u043f\u043e\u0440\u044f\u0434\u043a\u0443 \u2014 \u043e\u0431\u044b\u0447\u043d\u043e \u043e\u043a\u043e\u043b\u043e \u043f\u044f\u0442\u0438 \u0443 \u0437\u0434\u043e\u0440\u043e\u0432\u044b\u0445 \u0432\u0437\u0440\u043e\u0441\u043b\u044b\u0445."],["\u041f\u0440\u044f\u043c\u043e\u0439 \u0438\u043b\u0438 \u043e\u0431\u0440\u0430\u0442\u043d\u044b\u0439?","\u041f\u0440\u044f\u043c\u043e\u0439 \u2014 \u0432 \u043f\u043e\u043a\u0430\u0437\u0430\u043d\u043d\u043e\u043c \u043f\u043e\u0440\u044f\u0434\u043a\u0435; \u043e\u0431\u0440\u0430\u0442\u043d\u044b\u0439 (\u0432 \u043e\u0431\u0440\u0430\u0442\u043d\u043e\u043c) \u0441\u043b\u043e\u0436\u043d\u0435\u0435 \u0438 \u0441\u0438\u043b\u044c\u043d\u0435\u0435 \u0433\u0440\u0443\u0437\u0438\u0442 \u0440\u0430\u0431\u043e\u0447\u0443\u044e \u043f\u0430\u043c\u044f\u0442\u044c."],["\u0423\u043b\u0443\u0447\u0448\u0430\u0435\u0442 \u043f\u0430\u043c\u044f\u0442\u044c \u0432\u043e\u043e\u0431\u0449\u0435?","\u0423\u043b\u0443\u0447\u0448\u0430\u0435\u0442 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442 \u041a\u043e\u0440\u0441\u0438 \u0438 \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0439 \u043e\u0431\u044a\u0451\u043c; \u0448\u0438\u0440\u043e\u043a\u0438\u0439 \u043f\u0435\u0440\u0435\u043d\u043e\u0441 \u043e\u0433\u0440\u0430\u043d\u0438\u0447\u0435\u043d."]],variants:"\u041f\u0440\u044f\u043c\u0430\u044f \u0438 \u043e\u0431\u0440\u0430\u0442\u043d\u0430\u044f \u0432\u0435\u0440\u0441\u0438\u0438; \u0431\u043e\u043b\u0435\u0435 \u0434\u043b\u0438\u043d\u043d\u044b\u0435 \u0446\u0435\u043f\u043e\u0447\u043a\u0438; \u0443\u0441\u043a\u043e\u0440\u0435\u043d\u043d\u044b\u0439 \u043f\u043e\u043a\u0430\u0437; \u0440\u0430\u0441\u043a\u043b\u0430\u0434\u043a\u0438 \u0432 \u0432\u0438\u0434\u0435 2D-\u0441\u0435\u0442\u043a\u0438 \u0438\u043b\u0438 3D-\u0431\u043b\u043e\u043a\u043e\u0432."},en:{about:"A set of blocks lights up in a sequence; you tap them back in the same order. The sequence grows until you can no longer reproduce it \u2014 that length is your spatial span.",benefit:"Visuospatial short-term and working memory \u2014 holding and reproducing a pattern of locations in order, the spatial counterpart of digit span.",history:"Since the early 1970s it has been one of the standard neuropsychological tests of spatial memory, used in clinics and thousands of studies because it needs almost no language.",creator:"Canadian-Italian psychologist Philip Corsi, who developed it in the early 1970s (1971\u201372) while working with Brenda Milner at McGill University.",methods:"Watch the whole sequence before you start tapping; do not move until it finishes. Chunk longer runs into shapes or paths. Push to the length where you fail about half the time \u2014 that edge is where span grows.",duration:"Short daily sessions of a few minutes. Spatial span is fairly stable, so expect modest, gradual gains rather than dramatic jumps.",research:"A well-validated measure of spatial span; the average healthy adult reproduces around five blocks. Practice raises your score on the task, but as with all span training, broad transfer to unrelated abilities is limited.",rec:"Use it to benchmark and gently push spatial memory. Compare your span to your own past results, not to a \"normal\" number.",faq:[["What is spatial span?","The longest sequence of locations you can reproduce in order \u2014 typically around five for healthy adults."],["Forward or backward?","Forward taps in the shown order; backward (reverse order) is harder and loads working memory more."],["Does it improve memory generally?","It improves your Corsi score and spatial span; broad memory transfer is limited."]],variants:"Forward and backward (reverse-order) versions; longer sequences; faster presentation; and 2D-grid or 3D-block layouts."},es:{about:"Un conjunto de bloques se ilumina en una secuencia; t\xfa los tocas de vuelta en el mismo orden. La secuencia crece hasta que ya no puedes reproducirla: esa longitud es tu amplitud espacial.",benefit:"Memoria visoespacial a corto plazo y de trabajo: retener y reproducir en orden un patr\xf3n de ubicaciones, el equivalente espacial de la amplitud de d\xedgitos.",history:"Desde principios de los a\xf1os setenta ha sido una de las pruebas neuropsicol\xf3gicas est\xe1ndar de la memoria espacial, usada en cl\xednicas y en miles de estudios porque casi no requiere lenguaje.",creator:"El psic\xf3logo \xedtalo-canadiense Philip Corsi, que lo desarroll\xf3 a principios de los a\xf1os setenta (1971-72) mientras trabajaba con Brenda Milner en la Universidad McGill.",methods:"Observa la secuencia entera antes de empezar a tocar; no te muevas hasta que termine. Agrupa las series largas en formas o trayectos. Empuja hasta la longitud en la que fallas alrededor de la mitad de las veces: ese l\xedmite es donde crece la amplitud.",duration:"Sesiones diarias cortas de unos pocos minutos. La amplitud espacial es bastante estable, as\xed que espera mejoras modestas y graduales en lugar de saltos espectaculares.",research:"Una medida bien validada de la amplitud espacial; el adulto sano promedio reproduce alrededor de cinco bloques. La pr\xe1ctica eleva tu puntuaci\xf3n en la tarea, pero, como con todo entrenamiento de amplitud, la transferencia amplia a habilidades no relacionadas es limitada.",rec:"\xdasalo para medir y empujar con suavidad la memoria espacial. Compara tu amplitud con tus propios resultados anteriores, no con una cifra \"normal\".",faq:[["\xbfQu\xe9 es la amplitud espacial?","La secuencia m\xe1s larga de ubicaciones que puedes reproducir en orden: t\xedpicamente alrededor de cinco en adultos sanos."],["\xbfHacia delante o hacia atr\xe1s?","Hacia delante se toca en el orden mostrado; hacia atr\xe1s (orden inverso) es m\xe1s dif\xedcil y exige m\xe1s a la memoria de trabajo."],["\xbfMejora la memoria en general?","Mejora tu puntuaci\xf3n en Corsi y tu amplitud espacial; la transferencia amplia a la memoria es limitada."]],variants:"Versiones hacia delante y hacia atr\xe1s (orden inverso); secuencias m\xe1s largas; presentaci\xf3n m\xe1s r\xe1pida; y disposiciones en cuadr\xedcula 2D o en bloques 3D."},de:{about:"Eine Reihe von Bl\xf6cken leuchtet in einer Abfolge auf; du tippst sie in derselben Reihenfolge wieder an. Die Abfolge wird l\xe4nger, bis du sie nicht mehr wiedergeben kannst \u2013 diese L\xe4nge ist deine r\xe4umliche Merkspanne.",benefit:"Visuell-r\xe4umliches Kurzzeit- und Arbeitsged\xe4chtnis \u2013 ein Muster von Orten in Reihenfolge festzuhalten und wiederzugeben, das r\xe4umliche Gegenst\xfcck zur Zahlenspanne.",history:"Seit den fr\xfchen 1970er-Jahren ist es einer der neuropsychologischen Standardtests f\xfcr das r\xe4umliche Ged\xe4chtnis, eingesetzt in Kliniken und in Tausenden von Studien, weil er nahezu ohne Sprache auskommt.",creator:"Der kanadisch-italienische Psychologe Philip Corsi, der ihn Anfang der 1970er-Jahre (1971\u201372) w\xe4hrend seiner Arbeit mit Brenda Milner an der McGill University entwickelte.",methods:"Beobachte die gesamte Abfolge, bevor du zu tippen beginnst; r\xfchre dich nicht, bis sie zu Ende ist. Fasse l\xe4ngere Folgen zu Formen oder Pfaden zusammen. Treibe dich bis zu der L\xe4nge, bei der du etwa die H\xe4lfte der Versuche scheiterst \u2013 an dieser Grenze w\xe4chst die Merkspanne.",duration:"Kurze t\xe4gliche Einheiten von wenigen Minuten. Die r\xe4umliche Merkspanne ist recht stabil, erwarte also eher bescheidene, allm\xe4hliche Zugewinne als sprunghafte Fortschritte.",research:"Ein gut validiertes Ma\xdf f\xfcr die r\xe4umliche Merkspanne; der durchschnittliche gesunde Erwachsene gibt etwa f\xfcnf Bl\xf6cke wieder. \xdcbung steigert deinen Wert in der Aufgabe, doch wie bei jedem Span-Training ist der breite Transfer auf unabh\xe4ngige F\xe4higkeiten begrenzt.",rec:"Nutze es, um dein r\xe4umliches Ged\xe4chtnis einzuordnen und behutsam zu fordern. Vergleiche deine Spanne mit deinen eigenen fr\xfcheren Ergebnissen, nicht mit einer \"normalen\" Zahl.",faq:[["Was ist die r\xe4umliche Merkspanne?","Die l\xe4ngste Folge von Orten, die du in Reihenfolge wiedergeben kannst \u2013 typischerweise etwa f\xfcnf bei gesunden Erwachsenen."],["Vorw\xe4rts oder r\xfcckw\xe4rts?","Vorw\xe4rts tippst du in der gezeigten Reihenfolge; r\xfcckw\xe4rts (in umgekehrter Reihenfolge) ist schwerer und belastet das Arbeitsged\xe4chtnis st\xe4rker."],["Verbessert es das Ged\xe4chtnis allgemein?","Es verbessert deinen Corsi-Wert und deine r\xe4umliche Merkspanne; der breite Ged\xe4chtnistransfer ist begrenzt."]],variants:"Vorw\xe4rts- und R\xfcckw\xe4rtsversionen (umgekehrte Reihenfolge); l\xe4ngere Abfolgen; schnellere Darbietung; sowie 2D-Raster- oder 3D-Block-Anordnungen."},pt:{about:"Um conjunto de blocos acende numa sequ\xeancia; voc\xea toca neles de volta na mesma ordem. A sequ\xeancia cresce at\xe9 voc\xea n\xe3o conseguir mais reproduzi-la \u2014 esse comprimento \xe9 o seu span espacial.",benefit:"Mem\xf3ria visuoespacial de curto prazo e de trabalho \u2014 reter e reproduzir um padr\xe3o de posi\xe7\xf5es em ordem, a contraparte espacial do span de d\xedgitos.",history:"Desde o in\xedcio dos anos 1970 \xe9 um dos testes neuropsicol\xf3gicos padr\xe3o de mem\xf3ria espacial, usado em cl\xednicas e em milhares de estudos por quase n\xe3o exigir linguagem.",creator:"O psic\xf3logo \xedtalo-canadense Philip Corsi, que o desenvolveu no in\xedcio dos anos 1970 (1971\u201372) enquanto trabalhava com Brenda Milner na Universidade McGill.",methods:"Observe a sequ\xeancia inteira antes de come\xe7ar a tocar; n\xe3o se mexa at\xe9 ela terminar. Agrupe sequ\xeancias mais longas em formas ou trajetos. V\xe1 at\xe9 o comprimento em que voc\xea erra cerca de metade das vezes \u2014 \xe9 nessa fronteira que o span cresce.",duration:"Sess\xf5es di\xe1rias curtas, de alguns minutos. O span espacial \xe9 bastante est\xe1vel, ent\xe3o espere ganhos modestos e graduais, e n\xe3o saltos dram\xe1ticos.",research:"Uma medida bem validada de span espacial; o adulto saud\xe1vel m\xe9dio reproduz cerca de cinco blocos. A pr\xe1tica aumenta a sua pontua\xe7\xe3o na tarefa, mas, como em todo treino de span, a transfer\xeancia ampla para habilidades n\xe3o relacionadas \xe9 limitada.",rec:"Use-o para medir e empurrar suavemente a mem\xf3ria espacial. Compare o seu span com os seus pr\xf3prios resultados anteriores, n\xe3o com um n\xfamero 'normal'.",faq:[["O que \xe9 span espacial?","A maior sequ\xeancia de posi\xe7\xf5es que voc\xea consegue reproduzir em ordem \u2014 em geral por volta de cinco para adultos saud\xe1veis."],["Direto ou invertido?","No direto voc\xea toca na ordem mostrada; o invertido (ordem reversa) \xe9 mais dif\xedcil e exige mais da mem\xf3ria de trabalho."],["Ele melhora a mem\xf3ria de modo geral?","Ele melhora a sua pontua\xe7\xe3o no Corsi e o span espacial; a transfer\xeancia ampla para a mem\xf3ria \xe9 limitada."]],variants:"Vers\xf5es direta e invertida (ordem reversa); sequ\xeancias mais longas; apresenta\xe7\xe3o mais r\xe1pida; e layouts em grade 2D ou em blocos 3D."},hi:{about:"\u0915\u0941\u091b \u092c\u094d\u0932\u0949\u0915 \u090f\u0915 \u0915\u094d\u0930\u092e \u092e\u0947\u0902 \u091c\u0932\u0924\u0947 \u0939\u0948\u0902; \u0906\u092a\u0915\u094b \u0909\u0928\u094d\u0939\u0947\u0902 \u0909\u0938\u0940 \u0915\u094d\u0930\u092e \u092e\u0947\u0902 \u0926\u092c\u093e\u0915\u0930 \u0926\u094b\u0939\u0930\u093e\u0928\u093e \u0939\u094b\u0924\u093e \u0939\u0948\u0964 \u0915\u094d\u0930\u092e \u0924\u092c \u0924\u0915 \u0932\u0902\u092c\u093e \u0939\u094b\u0924\u093e \u091c\u093e\u0924\u093e \u0939\u0948 \u091c\u092c \u0924\u0915 \u0906\u092a \u0909\u0938\u0947 \u0926\u094b\u092c\u093e\u0930\u093e \u0928\u0939\u0940\u0902 \u0915\u0930 \u092a\u093e\u0924\u0947 \u2014 \u0935\u0939\u0940 \u0932\u0902\u092c\u093e\u0908 \u0906\u092a\u0915\u0940 \u0938\u094d\u0925\u093e\u0928\u093f\u0915 \u0938\u094d\u092e\u0943\u0924\u093f-\u0938\u0940\u092e\u093e (spatial span) \u0939\u0948\u0964",benefit:"\u0926\u0943\u0936\u094d\u092f-\u0938\u094d\u0925\u093e\u0928\u093f\u0915 \u0905\u0932\u094d\u092a\u0915\u093e\u0932\u093f\u0915 \u0914\u0930 \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932 \u0938\u094d\u092e\u0943\u0924\u093f \u2014 \u091c\u0917\u0939\u094b\u0902 \u0915\u0947 \u090f\u0915 \u092a\u0948\u091f\u0930\u094d\u0928 \u0915\u094b \u0915\u094d\u0930\u092e \u092e\u0947\u0902 \u0925\u093e\u092e\u0928\u093e \u0914\u0930 \u0926\u094b\u0939\u0930\u093e\u0928\u093e, \u091c\u094b digit span \u0915\u093e \u0938\u094d\u0925\u093e\u0928\u093f\u0915 \u0938\u092e\u0915\u0915\u094d\u0937 \u0939\u0948\u0964",history:"1970 \u0915\u0947 \u0926\u0936\u0915 \u0915\u0940 \u0936\u0941\u0930\u0941\u0906\u0924 \u0938\u0947 \u092f\u0939 \u0938\u094d\u0925\u093e\u0928\u093f\u0915 \u0938\u094d\u092e\u0943\u0924\u093f \u0915\u0947 \u092e\u093e\u0928\u0915 \u0924\u0902\u0924\u094d\u0930\u093f\u0915\u093e-\u092e\u0928\u094b\u0935\u0948\u091c\u094d\u091e\u093e\u0928\u093f\u0915 \u092a\u0930\u0940\u0915\u094d\u0937\u0923\u094b\u0902 \u092e\u0947\u0902 \u0938\u0947 \u090f\u0915 \u0930\u0939\u093e \u0939\u0948, \u091c\u093f\u0938\u0915\u093e \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0915\u094d\u0932\u0940\u0928\u093f\u0915\u094b\u0902 \u0914\u0930 \u0939\u091c\u093c\u093e\u0930\u094b\u0902 \u0905\u0927\u094d\u092f\u092f\u0928\u094b\u0902 \u092e\u0947\u0902 \u0939\u094b\u0924\u093e \u0939\u0948, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u0907\u0938\u092e\u0947\u0902 \u092d\u093e\u0937\u093e \u0915\u0940 \u0932\u0917\u092d\u0917 \u091c\u093c\u0930\u0942\u0930\u0924 \u0939\u0940 \u0928\u0939\u0940\u0902 \u092a\u0921\u093c\u0924\u0940\u0964",creator:"\u0915\u0928\u093e\u0921\u093e\u0908-\u0907\u0924\u093e\u0932\u0935\u0940 \u092e\u0928\u094b\u0935\u0948\u091c\u094d\u091e\u093e\u0928\u093f\u0915 Philip Corsi, \u091c\u093f\u0928\u094d\u0939\u094b\u0902\u0928\u0947 \u0907\u0938\u0947 1970 \u0915\u0947 \u0926\u0936\u0915 \u0915\u0940 \u0936\u0941\u0930\u0941\u0906\u0924 (1971\u201372) \u092e\u0947\u0902 McGill University \u092e\u0947\u0902 Brenda Milner \u0915\u0947 \u0938\u093e\u0925 \u0915\u093e\u092e \u0915\u0930\u0924\u0947 \u0939\u0941\u090f \u0935\u093f\u0915\u0938\u093f\u0924 \u0915\u093f\u092f\u093e\u0964",methods:"\u0926\u092c\u093e\u0928\u093e \u0936\u0941\u0930\u0942 \u0915\u0930\u0928\u0947 \u0938\u0947 \u092a\u0939\u0932\u0947 \u092a\u0942\u0930\u093e \u0915\u094d\u0930\u092e \u0926\u0947\u0916 \u0932\u0940\u091c\u093f\u090f; \u091c\u092c \u0924\u0915 \u0935\u0939 \u0916\u093c\u0924\u094d\u092e \u0928 \u0939\u094b \u091c\u093e\u090f \u0924\u092c \u0924\u0915 \u0939\u093f\u0932\u093f\u090f \u092e\u0924\u0964 \u0932\u0902\u092c\u0947 \u0926\u094c\u0930\u094b\u0902 \u0915\u094b \u0906\u0915\u0943\u0924\u093f\u092f\u094b\u0902 \u092f\u093e \u0930\u093e\u0938\u094d\u0924\u094b\u0902 \u092e\u0947\u0902 \u092c\u093e\u0901\u091f \u0932\u0940\u091c\u093f\u090f\u0964 \u0909\u0938 \u0932\u0902\u092c\u093e\u0908 \u0924\u0915 \u092c\u0922\u093c\u093f\u090f \u091c\u0939\u093e\u0901 \u0906\u092a \u0915\u0930\u0940\u092c \u0906\u0927\u0940 \u092c\u093e\u0930 \u091a\u0942\u0915 \u091c\u093e\u0924\u0947 \u0939\u0948\u0902 \u2014 \u0935\u0939\u0940 \u0915\u093f\u0928\u093e\u0930\u093e \u0939\u0948 \u091c\u0939\u093e\u0901 span \u092c\u0922\u093c\u0924\u093e \u0939\u0948\u0964",duration:"\u0930\u094b\u091c\u093c \u0915\u0941\u091b \u092e\u093f\u0928\u091f \u0915\u0947 \u091b\u094b\u091f\u0947 \u0938\u0924\u094d\u0930\u0964 \u0938\u094d\u0925\u093e\u0928\u093f\u0915 span \u0915\u093e\u092b\u093c\u0940 \u0939\u0926 \u0924\u0915 \u0938\u094d\u0925\u093f\u0930 \u0930\u0939\u0924\u093e \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0928\u093e\u091f\u0915\u0940\u092f \u091b\u0932\u093e\u0901\u0917\u094b\u0902 \u0915\u0947 \u092c\u091c\u093e\u092f \u092e\u093e\u092e\u0942\u0932\u0940, \u0927\u0940\u092e\u0940 \u092a\u094d\u0930\u0917\u0924\u093f \u0915\u0940 \u0909\u092e\u094d\u092e\u0940\u0926 \u0915\u0940\u091c\u093f\u090f\u0964",research:"\u0938\u094d\u0925\u093e\u0928\u093f\u0915 span \u0915\u0940 \u090f\u0915 \u0905\u091a\u094d\u091b\u0940 \u0924\u0930\u0939 \u092a\u094d\u0930\u092e\u093e\u0923\u093f\u0924 \u092e\u093e\u092a; \u0914\u0938\u0924 \u0938\u094d\u0935\u0938\u094d\u0925 \u0935\u092f\u0938\u094d\u0915 \u0915\u0930\u0940\u092c \u092a\u093e\u0901\u091a \u092c\u094d\u0932\u0949\u0915 \u0926\u094b\u0939\u0930\u093e \u0932\u0947\u0924\u093e \u0939\u0948\u0964 \u0905\u092d\u094d\u092f\u093e\u0938 \u0938\u0947 \u0907\u0938 \u0915\u093e\u092e \u092e\u0947\u0902 \u0906\u092a\u0915\u093e \u0938\u094d\u0915\u094b\u0930 \u092c\u0922\u093c\u0924\u093e \u0939\u0948, \u092a\u0930 \u0939\u0930 span-\u091f\u094d\u0930\u0947\u0928\u093f\u0902\u0917 \u0915\u0940 \u0924\u0930\u0939, \u0905\u0938\u0902\u092c\u0902\u0927\u093f\u0924 \u0915\u094d\u0937\u092e\u0924\u093e\u0913\u0902 \u0924\u0915 \u0935\u094d\u092f\u093e\u092a\u0915 \u091f\u094d\u0930\u093e\u0902\u0938\u092b\u093c\u0930 \u0938\u0940\u092e\u093f\u0924 \u0939\u0940 \u0930\u0939\u0924\u093e \u0939\u0948\u0964",rec:"\u0907\u0938\u0915\u093e \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0905\u092a\u0928\u0940 \u0938\u094d\u0925\u093e\u0928\u093f\u0915 \u0938\u094d\u092e\u0943\u0924\u093f \u0915\u094b \u092e\u093e\u092a\u0928\u0947 \u0914\u0930 \u0939\u0932\u094d\u0915\u0947-\u0938\u0947 \u0906\u0917\u0947 \u092c\u0922\u093c\u093e\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0915\u0940\u091c\u093f\u090f\u0964 \u0905\u092a\u0928\u0947 span \u0915\u0940 \u0924\u0941\u0932\u0928\u093e \u0915\u093f\u0938\u0940 \"\u0938\u093e\u092e\u093e\u0928\u094d\u092f\" \u0938\u0902\u0916\u094d\u092f\u093e \u0938\u0947 \u0928\u0939\u0940\u0902, \u092c\u0932\u094d\u0915\u093f \u0905\u092a\u0928\u0947 \u0939\u0940 \u092a\u0941\u0930\u093e\u0928\u0947 \u0928\u0924\u0940\u091c\u094b\u0902 \u0938\u0947 \u0915\u0940\u091c\u093f\u090f\u0964",faq:[["spatial span \u0915\u094d\u092f\u093e \u0939\u0948?","\u091c\u0917\u0939\u094b\u0902 \u0915\u093e \u0935\u0939 \u0938\u092c\u0938\u0947 \u0932\u0902\u092c\u093e \u0915\u094d\u0930\u092e \u091c\u093f\u0938\u0947 \u0906\u092a \u0938\u0939\u0940 \u0915\u094d\u0930\u092e \u092e\u0947\u0902 \u0926\u094b\u0939\u0930\u093e \u0938\u0915\u0924\u0947 \u0939\u0948\u0902 \u2014 \u0938\u094d\u0935\u0938\u094d\u0925 \u0935\u092f\u0938\u094d\u0915\u094b\u0902 \u0915\u0947 \u0932\u093f\u090f \u0906\u092e\u0924\u094c\u0930 \u092a\u0930 \u0915\u0930\u0940\u092c \u092a\u093e\u0901\u091a\u0964"],["\u0906\u0917\u0947 \u0915\u0940 \u0913\u0930 \u092f\u093e \u0909\u0932\u094d\u091f\u093e?","\u0906\u0917\u0947 \u0915\u0940 \u0913\u0930 \u0935\u093e\u0932\u0947 \u092e\u0947\u0902 \u0926\u093f\u0916\u093e\u090f \u0917\u090f \u0915\u094d\u0930\u092e \u092e\u0947\u0902 \u0926\u092c\u093e\u0924\u0947 \u0939\u0948\u0902; \u0909\u0932\u094d\u091f\u093e (\u0935\u093f\u092a\u0930\u0940\u0924 \u0915\u094d\u0930\u092e) \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0915\u0920\u093f\u0928 \u0939\u0948 \u0914\u0930 \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932 \u0938\u094d\u092e\u0943\u0924\u093f \u092a\u0930 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u092c\u094b\u091d \u0921\u093e\u0932\u0924\u093e \u0939\u0948\u0964"],["\u0915\u094d\u092f\u093e \u092f\u0939 \u0906\u092e \u0924\u094c\u0930 \u092a\u0930 \u092f\u093e\u0926\u0926\u093e\u0936\u094d\u0924 \u0938\u0941\u0927\u093e\u0930\u0924\u093e \u0939\u0948?","\u092f\u0939 \u0906\u092a\u0915\u093e Corsi \u0938\u094d\u0915\u094b\u0930 \u0914\u0930 \u0938\u094d\u0925\u093e\u0928\u093f\u0915 span \u0938\u0941\u0927\u093e\u0930\u0924\u093e \u0939\u0948; \u0935\u094d\u092f\u093e\u092a\u0915 \u0938\u094d\u092e\u0943\u0924\u093f-\u091f\u094d\u0930\u093e\u0902\u0938\u092b\u093c\u0930 \u0938\u0940\u092e\u093f\u0924 \u0939\u0948\u0964"]],variants:"\u0906\u0917\u0947 \u0915\u0940 \u0913\u0930 \u0914\u0930 \u0909\u0932\u094d\u091f\u0947 (\u0935\u093f\u092a\u0930\u0940\u0924-\u0915\u094d\u0930\u092e) \u0938\u0902\u0938\u094d\u0915\u0930\u0923; \u0932\u0902\u092c\u0947 \u0915\u094d\u0930\u092e; \u0924\u0947\u091c\u093c \u092a\u094d\u0930\u0938\u094d\u0924\u0941\u0924\u093f; \u0914\u0930 2D-\u0917\u094d\u0930\u093f\u0921 \u092f\u093e 3D-\u092c\u094d\u0932\u0949\u0915 \u0935\u093e\u0932\u0947 \u0932\u0947\u0906\u0909\u091f\u0964"},zh:{about:"\u4e00\u7ec4\u65b9\u5757\u6309\u67d0\u4e2a\u987a\u5e8f\u4f9d\u6b21\u4eae\u8d77\uff0c\u4f60\u8981\u6309\u540c\u6837\u7684\u987a\u5e8f\u628a\u5b83\u4eec\u70b9\u56de\u53bb\u3002\u5e8f\u5217\u4f1a\u8d8a\u6765\u8d8a\u957f\uff0c\u76f4\u5230\u4f60\u518d\u4e5f\u590d\u73b0\u4e0d\u51fa\u6765\u2014\u2014\u90a3\u4e2a\u957f\u5ea6\u5c31\u662f\u4f60\u7684\u7a7a\u95f4\u5e7f\u5ea6\u3002",benefit:"\u89c6\u7a7a\u95f4\u77ed\u65f6\u8bb0\u5fc6\u548c\u5de5\u4f5c\u8bb0\u5fc6\u2014\u2014\u6309\u987a\u5e8f\u8bb0\u4f4f\u5e76\u590d\u73b0\u4e00\u7ec4\u4f4d\u7f6e\u6784\u6210\u7684\u56fe\u6848\uff0c\u76f8\u5f53\u4e8e\u6570\u5b57\u5e7f\u5ea6\u5728\u7a7a\u95f4\u4e0a\u7684\u5bf9\u5e94\u7248\u672c\u3002",history:"\u81ea20\u4e16\u7eaa70\u5e74\u4ee3\u521d\u4ee5\u6765\uff0c\u5b83\u4e00\u76f4\u662f\u6d4b\u91cf\u7a7a\u95f4\u8bb0\u5fc6\u7684\u6807\u51c6\u795e\u7ecf\u5fc3\u7406\u5b66\u6d4b\u9a8c\u4e4b\u4e00\uff0c\u88ab\u7528\u4e8e\u4e34\u5e8a\u548c\u6570\u4ee5\u5343\u8ba1\u7684\u7814\u7a76\uff0c\u56e0\u4e3a\u5b83\u51e0\u4e4e\u4e0d\u4f9d\u8d56\u8bed\u8a00\u3002",creator:"\u7531\u52a0\u62ff\u5927\u88d4\u610f\u5927\u5229\u7c4d\u5fc3\u7406\u5b66\u5bb6Philip Corsi\u63d0\u51fa\uff0c\u4ed6\u572820\u4e16\u7eaa70\u5e74\u4ee3\u521d\uff081971\u201372\u5e74\uff09\u4e8e\u9ea6\u5409\u5c14\u5927\u5b66\u4e0eBrenda Milner\u5171\u4e8b\u671f\u95f4\u5f00\u53d1\u4e86\u5b83\u3002",methods:"\u5148\u628a\u6574\u4e2a\u5e8f\u5217\u770b\u5b8c\u518d\u5f00\u59cb\u70b9\uff1b\u5e8f\u5217\u6ca1\u7ed3\u675f\u5c31\u522b\u52a8\u624b\u3002\u628a\u8f83\u957f\u7684\u5e8f\u5217\u5207\u6210\u5f62\u72b6\u6216\u8def\u5f84\u6765\u8bb0\u3002\u628a\u96be\u5ea6\u63a8\u5230\u4f60\u5927\u7ea6\u4e00\u534a\u51e0\u7387\u4f1a\u5931\u8d25\u7684\u957f\u5ea6\u2014\u2014\u90a3\u4e2a\u4e34\u754c\u70b9\u6b63\u662f\u5e7f\u5ea6\u589e\u957f\u7684\u5730\u65b9\u3002",duration:"\u6bcf\u5929\u51e0\u5206\u949f\u7684\u77ed\u65f6\u7ec3\u4e60\u3002\u7a7a\u95f4\u5e7f\u5ea6\u76f8\u5f53\u7a33\u5b9a\uff0c\u6240\u4ee5\u8981\u9884\u671f\u7684\u662f\u6e29\u548c\u3001\u6e10\u8fdb\u7684\u8fdb\u6b65\uff0c\u800c\u975e\u620f\u5267\u6027\u7684\u8dc3\u5347\u3002",research:"\u8fd9\u662f\u4e00\u9879\u7ecf\u8fc7\u5145\u5206\u9a8c\u8bc1\u7684\u7a7a\u95f4\u5e7f\u5ea6\u6307\u6807\uff1b\u5065\u5eb7\u6210\u5e74\u4eba\u5e73\u5747\u80fd\u590d\u73b0\u7ea6\u4e94\u4e2a\u65b9\u5757\u3002\u7ec3\u4e60\u4f1a\u63d0\u9ad8\u4f60\u5728\u8be5\u4efb\u52a1\u4e0a\u7684\u5206\u6570\uff0c\u4f46\u548c\u6240\u6709\u5e7f\u5ea6\u8bad\u7ec3\u4e00\u6837\uff0c\u5411\u65e0\u5173\u80fd\u529b\u7684\u5e7f\u6cdb\u8fc1\u79fb\u662f\u6709\u9650\u7684\u3002",rec:"\u7528\u5b83\u6765\u7ed9\u7a7a\u95f4\u8bb0\u5fc6\u505a\u57fa\u51c6\u6d4b\u91cf\u3001\u5e76\u6e29\u548c\u5730\u5f80\u4e0a\u63a8\u3002\u548c\u4f60\u81ea\u5df1\u8fc7\u53bb\u7684\u6210\u7ee9\u6bd4\uff0c\u800c\u4e0d\u662f\u548c\u67d0\u4e2a\u300c\u6b63\u5e38\u300d\u6570\u5b57\u6bd4\u3002",faq:[["\u4ec0\u4e48\u662f\u7a7a\u95f4\u5e7f\u5ea6\uff1f","\u4f60\u80fd\u6309\u987a\u5e8f\u590d\u73b0\u7684\u6700\u957f\u4f4d\u7f6e\u5e8f\u5217\u2014\u2014\u5065\u5eb7\u6210\u5e74\u4eba\u901a\u5e38\u5728\u4e94\u4e2a\u5de6\u53f3\u3002"],["\u6b63\u5e8f\u8fd8\u662f\u5012\u5e8f\uff1f","\u6b63\u5e8f\u662f\u6309\u663e\u793a\u7684\u987a\u5e8f\u70b9\uff1b\u5012\u5e8f\uff08\u53cd\u5411\u987a\u5e8f\uff09\u66f4\u96be\uff0c\u5bf9\u5de5\u4f5c\u8bb0\u5fc6\u7684\u8d1f\u8377\u4e5f\u66f4\u5927\u3002"],["\u5b83\u80fd\u6539\u5584\u6574\u4f53\u8bb0\u5fc6\u5417\uff1f","\u5b83\u80fd\u63d0\u9ad8\u4f60\u7684Corsi\u5206\u6570\u548c\u7a7a\u95f4\u5e7f\u5ea6\uff1b\u5411\u66f4\u5e7f\u8bb0\u5fc6\u7684\u8fc1\u79fb\u5219\u6709\u9650\u3002"]],variants:"\u6b63\u5e8f\u548c\u5012\u5e8f\uff08\u53cd\u5411\u987a\u5e8f\uff09\u7248\u672c\uff1b\u66f4\u957f\u7684\u5e8f\u5217\uff1b\u66f4\u5feb\u7684\u5448\u73b0\u901f\u5ea6\uff1b\u4ee5\u53ca\u4e8c\u7ef4\u65b9\u683c\u6216\u4e09\u7ef4\u65b9\u5757\u7684\u5e03\u5c40\u3002"}},counter:{ru:{about:"\xab\u0421\u0447\u0451\u0442\u0447\u0438\u043a: \u041c\u0430\u0442\u0435\u043c\u0430\u0442\u0438\u043a\u0430\xbb \u2014 \u044d\u0442\u043e \u0430\u0440\u0438\u0444\u043c\u0435\u0442\u0438\u0447\u0435\u0441\u043a\u0438\u0439 \u0442\u0440\u0435\u043d\u0430\u0436\u0451\u0440 \u043d\u0430 \u0432\u0440\u0435\u043c\u044f. \u041d\u0430 \u044d\u043a\u0440\u0430\u043d\u0435 \u043f\u043e\u044f\u0432\u043b\u044f\u0435\u0442\u0441\u044f \u043a\u043e\u0440\u043e\u0442\u043a\u0430\u044f \u0446\u0435\u043f\u043e\u0447\u043a\u0430 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0439 \u0438\u043b\u0438 \u043e\u0434\u0438\u043d \u043f\u0440\u0438\u043c\u0435\u0440, \u0438 \u043d\u0443\u0436\u043d\u043e \u043f\u043e\u0441\u0447\u0438\u0442\u0430\u0442\u044c \u043e\u0442\u0432\u0435\u0442 \u0432 \u0443\u043c\u0435 \u0438 \u0432\u0432\u0435\u0441\u0442\u0438 \u0435\u0433\u043e, \u043f\u043e\u043a\u0430 \u043d\u0435 \u0432\u044b\u0448\u043b\u043e \u0432\u0440\u0435\u043c\u044f, \u0430 \u0437\u0430\u0442\u0435\u043c \u0441\u0440\u0430\u0437\u0443 \u043f\u0435\u0440\u0435\u0445\u043e\u0434\u0438\u0442\u044c \u043a \u0441\u043b\u0435\u0434\u0443\u044e\u0449\u0435\u043c\u0443.",benefit:"\u0422\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u0440\u0430\u0431\u043e\u0447\u0443\u044e \u043f\u0430\u043c\u044f\u0442\u044c \u0438 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u043e\u0431\u0440\u0430\u0431\u043e\u0442\u043a\u0438 \u0447\u0438\u0441\u0435\u043b: \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0442\u044c \u0432 \u0443\u043c\u0435 \u043f\u0440\u043e\u043c\u0435\u0436\u0443\u0442\u043e\u0447\u043d\u044b\u0435 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442\u044b, \u043f\u0440\u0438\u043c\u0435\u043d\u044f\u0442\u044c \u043d\u0443\u0436\u043d\u043e\u0435 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435 \u0438 \u0431\u044b\u0441\u0442\u0440\u043e, \u0431\u0435\u0437 \u043e\u0448\u0438\u0431\u043e\u043a \u0434\u043e\u0441\u0442\u0430\u0432\u0430\u0442\u044c \u0438\u0437 \u043f\u0430\u043c\u044f\u0442\u0438 \u0431\u0430\u0437\u043e\u0432\u044b\u0435 \u0447\u0438\u0441\u043b\u043e\u0432\u044b\u0435 \u0444\u0430\u043a\u0442\u044b \u043f\u043e\u0434 \u0434\u0430\u0432\u043b\u0435\u043d\u0438\u0435\u043c \u0432\u0440\u0435\u043c\u0435\u043d\u0438.",history:"\u0423\u0441\u0442\u043d\u044b\u0439 \u0441\u0447\u0451\u0442 \u2014 \u043e\u0434\u0438\u043d \u0438\u0437 \u0434\u0440\u0435\u0432\u043d\u0435\u0439\u0448\u0438\u0445 \u043d\u0430\u0432\u044b\u043a\u043e\u0432, \u043a\u043e\u0442\u043e\u0440\u043e\u043c\u0443 \u0432\u0435\u043a\u0430\u043c\u0438 \u0443\u0447\u0438\u043b\u0438 \u043d\u0430 \u0430\u0431\u0430\u043a\u0435 \u0438 \u0441\u043e\u0440\u043e\u0431\u0430\u043d\u0435, \u0430 \u0442\u0430\u043a\u0436\u0435 \u0447\u0435\u0440\u0435\u0437 \u043f\u043e\u0432\u0441\u0435\u0434\u043d\u0435\u0432\u043d\u0443\u044e \u0442\u043e\u0440\u0433\u043e\u0432\u0443\u044e \u0430\u0440\u0438\u0444\u043c\u0435\u0442\u0438\u043a\u0443. \u0421\u0438\u0441\u0442\u0435\u043c\u044b \u0431\u044b\u0441\u0442\u0440\u043e\u0433\u043e \u0441\u0447\u0451\u0442\u0430 \u2014 \u044f\u043f\u043e\u043d\u0441\u043a\u0438\u0439 \u043c\u0435\u043d\u0442\u0430\u043b\u044c\u043d\u044b\u0439 \u0430\u0431\u0430\u043a\u0443\u0441 (\u0438 \u0435\u0433\u043e \u043e\u0442\u0432\u0435\u0442\u0432\u043b\u0435\u043d\u0438\u0435 \u0444\u043b\u0435\u0448-\u0430\u043d\u0434\u0437\u0430\u043d), \u0432\u0435\u0434\u0438\u0447\u0435\u0441\u043a\u0430\u044f \u043c\u0430\u0442\u0435\u043c\u0430\u0442\u0438\u043a\u0430, \u043c\u0435\u0442\u043e\u0434 \u0422\u0440\u0430\u0445\u0442\u0435\u043d\u0431\u0435\u0440\u0433\u0430 \u2014 \u043f\u043e\u0437\u0436\u0435 \u0444\u043e\u0440\u043c\u0430\u043b\u0438\u0437\u043e\u0432\u0430\u043b\u0438 \u043f\u0440\u0438\u0451\u043c\u044b, \u0443\u0441\u043a\u043e\u0440\u044f\u044e\u0449\u0438\u0435 \u0432\u044b\u0447\u0438\u0441\u043b\u0435\u043d\u0438\u044f, \u0430 \u0430\u0440\u0438\u0444\u043c\u0435\u0442\u0438\u0447\u0435\u0441\u043a\u0438\u0435 \u0442\u0440\u0435\u043d\u0430\u0436\u0451\u0440\u044b \u043d\u0430 \u0432\u0440\u0435\u043c\u044f \u0432\u0440\u043e\u0434\u0435 \u044d\u0442\u043e\u0433\u043e \u0441\u0442\u0430\u043b\u0438 \u0446\u0438\u0444\u0440\u043e\u0432\u044b\u043c \u043f\u0440\u043e\u0434\u043e\u043b\u0436\u0435\u043d\u0438\u0435\u043c \u0442\u043e\u0439 \u0434\u0430\u0432\u043d\u0435\u0439 \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u0438.",creator:"\u0415\u0434\u0438\u043d\u043e\u0433\u043e \u0430\u0432\u0442\u043e\u0440\u0430 \u043d\u0435\u0442 \u2014 \u0443\u0441\u0442\u043d\u044b\u0439 \u0441\u0447\u0451\u0442 \u044d\u0442\u043e \u043e\u0431\u0449\u0435\u0435 \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u0435 \u0438\u0437 \u0448\u0438\u0440\u043e\u043a\u043e\u0439 \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u0438 \u043e\u0431\u0443\u0447\u0435\u043d\u0438\u044f \u043d\u0430 \u0430\u0431\u0430\u043a\u0435 \u0438 \u0448\u043a\u043e\u043b\u044c\u043d\u043e\u0439 \u0430\u0440\u0438\u0444\u043c\u0435\u0442\u0438\u043a\u0438. \u0412\u043e\u043a\u0440\u0443\u0433 \u043d\u0435\u0433\u043e \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044e\u0442 \u0438\u043c\u0435\u043d\u043d\u044b\u0435 \u0441\u0438\u0441\u0442\u0435\u043c\u044b: \u043c\u0435\u0442\u043e\u0434 \u0422\u0440\u0430\u0445\u0442\u0435\u043d\u0431\u0435\u0440\u0433\u0430 \u0440\u0430\u0437\u0440\u0430\u0431\u043e\u0442\u0430\u043b \u042f\u043a\u043e\u0432 \u0422\u0440\u0430\u0445\u0442\u0435\u043d\u0431\u0435\u0440\u0433 \u0432 \u0441\u0435\u0440\u0435\u0434\u0438\u043d\u0435 XX \u0432\u0435\u043a\u0430, \u0432\u0435\u0434\u0438\u0447\u0435\u0441\u043a\u0443\u044e \u043c\u0430\u0442\u0435\u043c\u0430\u0442\u0438\u043a\u0443 \u043f\u043e\u043f\u0443\u043b\u044f\u0440\u0438\u0437\u0438\u0440\u043e\u0432\u0430\u043b \u0411\u0445\u0430\u0440\u0430\u0442\u0438 \u041a\u0440\u0438\u0448\u043d\u0430 \u0422\u0438\u0440\u0442\u0445\u0430 \u0432 \u043a\u043d\u0438\u0433\u0435, \u0438\u0437\u0434\u0430\u043d\u043d\u043e\u0439 \u0432 1965 \u0433\u043e\u0434\u0443, \u043d\u043e \u0441\u0430\u043c \u043d\u0430\u0432\u044b\u043a \u0441\u0442\u0430\u0440\u0448\u0435 \u0438\u0445 \u0432\u0441\u0435\u0445.",methods:"\u041d\u0435 \u043f\u0440\u043e\u0433\u043e\u0432\u0430\u0440\u0438\u0432\u0430\u0439\u0442\u0435 \u0447\u0438\u0441\u043b\u043e \u043f\u043e \u0446\u0438\u0444\u0440\u0435 \u2014 \u0443\u0447\u0438\u0442\u0435\u0441\u044c \u0440\u0430\u0437\u0431\u0438\u0432\u0430\u0442\u044c \u043d\u0430 \u0443\u0434\u043e\u0431\u043d\u044b\u0435 \u0447\u0430\u0441\u0442\u0438 \u0438 \u043e\u043a\u0440\u0443\u0433\u043b\u044f\u0442\u044c (\u0441\u0447\u0438\u0442\u0430\u0439\u0442\u0435 48 \u043a\u0430\u043a 50 \u043c\u0438\u043d\u0443\u0441 2). \u0414\u043e\u0432\u0435\u0434\u0438\u0442\u0435 \u0434\u043e \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0437\u043c\u0430 \u043e\u043f\u043e\u0440\u043d\u044b\u0435 \u0431\u043b\u043e\u043a\u0438: \u0442\u0430\u0431\u043b\u0438\u0446\u0443 \u0443\u043c\u043d\u043e\u0436\u0435\u043d\u0438\u044f, \u0434\u043e\u043f\u043e\u043b\u043d\u0435\u043d\u0438\u044f \u0434\u043e 10 \u0438 100, \u0447\u0442\u043e\u0431\u044b \u043e\u0442\u0432\u0435\u0442 \u0432\u0441\u043f\u043b\u044b\u0432\u0430\u043b \u0441\u0430\u043c. \u0421\u043d\u0430\u0447\u0430\u043b\u0430 \u043d\u0430\u0431\u0435\u0440\u0438\u0442\u0435 \u043a\u043e\u043c\u0444\u043e\u0440\u0442\u043d\u0443\u044e \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c, \u043f\u043e\u0442\u043e\u043c \u0435\u0451 \u043f\u043e\u0434\u0440\u0435\u0437\u0430\u0439\u0442\u0435: \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u044c \u043f\u0440\u0438 \u0443\u043c\u0435\u0440\u0435\u043d\u043d\u043e\u043c \u0446\u0435\u0439\u0442\u043d\u043e\u0442\u0435 \u0432\u0430\u0436\u043d\u0435\u0435 \u043b\u0438\u0445\u0438\u0445 \u0443\u0433\u0430\u0434\u044b\u0432\u0430\u043d\u0438\u0439.",duration:"\u041b\u0443\u0447\u0448\u0435 \u0432\u0441\u0435\u0433\u043e \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u0435 \u0447\u0430\u0441\u0442\u044b\u0435 \u043f\u043e\u0434\u0445\u043e\u0434\u044b: 5\u201310 \u043c\u0438\u043d\u0443\u0442 \u0432 \u0434\u0435\u043d\u044c \u043f\u043e\u043b\u0435\u0437\u043d\u0435\u0435 \u043e\u0434\u043d\u043e\u0433\u043e \u0434\u043e\u043b\u0433\u043e\u0433\u043e \u0437\u0430\u043d\u044f\u0442\u0438\u044f \u0440\u0430\u0437 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e. \u041e\u0441\u0442\u0430\u043d\u0430\u0432\u043b\u0438\u0432\u0430\u0439\u0442\u0435\u0441\u044c, \u043a\u043e\u0433\u0434\u0430 \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u044c \u043d\u0430\u0447\u0438\u043d\u0430\u0435\u0442 \u043f\u0430\u0434\u0430\u0442\u044c, \u2014 \u0443\u0441\u0442\u0430\u043b\u043e\u0441\u0442\u044c \u0437\u0430\u043a\u0440\u0435\u043f\u043b\u044f\u0435\u0442 \u043d\u0435\u0431\u0440\u0435\u0436\u043d\u043e\u0441\u0442\u044c, \u0430 \u043d\u0435 \u0431\u0435\u0433\u043b\u043e\u0441\u0442\u044c.",research:"\u041d\u0430\u0434\u0451\u0436\u043d\u043e \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043d\u043e \u043e\u0447\u0435\u0432\u0438\u0434\u043d\u043e\u0435: \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0448\u044c \u0443\u0441\u0442\u043d\u044b\u0439 \u0441\u0447\u0451\u0442 \u2014 \u0438\u0437\u043c\u0435\u0440\u0438\u043c\u043e \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u0438 \u0442\u043e\u0447\u043d\u0435\u0435 \u0441\u0447\u0438\u0442\u0430\u0435\u0448\u044c \u0432 \u0443\u043c\u0435, \u0438 \u0440\u0430\u0431\u043e\u0447\u0430\u044f \u043f\u0430\u043c\u044f\u0442\u044c \u0443\u0441\u0442\u043e\u0439\u0447\u0438\u0432\u043e \u0441\u0432\u044f\u0437\u0430\u043d\u0430 \u0441 \u0430\u0440\u0438\u0444\u043c\u0435\u0442\u0438\u0447\u0435\u0441\u043a\u0438\u043c\u0438 \u043d\u0430\u0432\u044b\u043a\u0430\u043c\u0438. \u0421 \u0433\u0440\u043e\u043c\u043a\u0438\u043c\u0438 \u0437\u0430\u044f\u0432\u043b\u0435\u043d\u0438\u044f\u043c\u0438 \u0445\u0443\u0436\u0435: \u0448\u0438\u0440\u043e\u043a\u0438\u0439 \u043f\u0435\u0440\u0435\u043d\u043e\u0441 \u043d\u0430 \u043e\u0431\u0449\u0438\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0438\u043b\u0438 \u043d\u0435\u0441\u0432\u044f\u0437\u0430\u043d\u043d\u044b\u0435 \u0431\u044b\u0442\u043e\u0432\u044b\u0435 \u0437\u0430\u0434\u0430\u0447\u0438 \u0432 \u043e\u0441\u043d\u043e\u0432\u043d\u043e\u043c \u043d\u0435 \u0434\u043e\u043a\u0430\u0437\u0430\u043d, \u0442\u0440\u0435\u043d\u0430\u0436\u0451\u0440\u044b \u0434\u043b\u044f \u043c\u043e\u0437\u0433\u0430 \u0432 \u0441\u0442\u0440\u043e\u0433\u0438\u0445 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u044f\u0445 \u0440\u0430\u0437 \u0437\u0430 \u0440\u0430\u0437\u043e\u043c \u043d\u0435 \u043f\u043e\u043a\u0430\u0437\u044b\u0432\u0430\u044e\u0442 \u0434\u0430\u043b\u044c\u043d\u0435\u0433\u043e \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0430, \u0438 \u0434\u0430\u0436\u0435 \u043f\u043e \u043c\u0435\u043d\u0442\u0430\u043b\u044c\u043d\u043e\u043c\u0443 \u0430\u0431\u0430\u043a\u0443\u0441\u0443 \u0443\u0447\u0451\u043d\u044b\u0435 \u0441\u043f\u043e\u0440\u044f\u0442, \u0440\u0430\u0441\u0442\u0451\u0442 \u043b\u0438 \u043e\u0442 \u043d\u0435\u0433\u043e \u0441\u0430\u043c\u0430 \u0440\u0430\u0431\u043e\u0447\u0430\u044f \u043f\u0430\u043c\u044f\u0442\u044c. \u041a \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f\u043c \xab+IQ\xbb \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u0435\u0441\u044c \u0441\u043a\u0435\u043f\u0442\u0438\u0447\u0435\u0441\u043a\u0438.",rec:"\u0414\u0435\u0440\u0436\u0438\u0442\u0435 \u0441\u043b\u043e\u0436\u043d\u043e\u0441\u0442\u044c \u0447\u0443\u0442\u044c \u0432\u044b\u0448\u0435 \u043a\u043e\u043c\u0444\u043e\u0440\u0442\u043d\u043e\u0439 \u2014 \u043f\u0440\u0438\u043c\u0435\u0440\u044b, \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u0440\u0435\u0448\u0430\u044e\u0442\u0441\u044f \u0437\u0430 \u043f\u0430\u0440\u0443 \u0441\u0435\u043a\u0443\u043d\u0434 \u0441 \u0443\u0441\u0438\u043b\u0438\u0435\u043c, \u2014 \u0438 \u0437\u0430\u043d\u0438\u043c\u0430\u0439\u0442\u0435\u0441\u044c \u043a\u0430\u0436\u0434\u044b\u0439 \u0434\u0435\u043d\u044c \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u043c\u0438 \u043f\u043e\u0434\u0445\u043e\u0434\u0430\u043c\u0438, \u0430 \u043d\u0435 \u0440\u0435\u0434\u043a\u0438\u043c\u0438 \u043c\u0430\u0440\u0430\u0444\u043e\u043d\u0430\u043c\u0438.",faq:[["\u0421\u0442\u0430\u043d\u0443 \u043b\u0438 \u044f \u0443\u043c\u043d\u0435\u0435, \u043f\u043e\u0434\u043d\u0438\u043c\u0435\u0442\u0441\u044f \u043b\u0438 IQ?","\u0427\u0435\u0441\u0442\u043d\u043e \u2014 \u043d\u0435\u0442. \u0412\u044b \u0437\u0430\u043c\u0435\u0442\u043d\u043e \u043b\u0443\u0447\u0448\u0435 \u0438 \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u0431\u0443\u0434\u0435\u0442\u0435 \u0441\u0447\u0438\u0442\u0430\u0442\u044c \u0432 \u0443\u043c\u0435, \u043d\u043e \u043d\u0430\u0434\u0451\u0436\u043d\u044b\u0445 \u0434\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432, \u0447\u0442\u043e \u044d\u0442\u043e \u043f\u043e\u0432\u044b\u0448\u0430\u0435\u0442 \u043e\u0431\u0449\u0438\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0438\u043b\u0438 \u043d\u0435\u0441\u0432\u044f\u0437\u0430\u043d\u043d\u044b\u0435 \u043d\u0430\u0432\u044b\u043a\u0438, \u043f\u043e\u0447\u0442\u0438 \u043d\u0435\u0442, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u043c\u044b \u044d\u0442\u043e\u0433\u043e \u043d\u0435 \u043e\u0431\u0435\u0449\u0430\u0435\u043c."],["\u042d\u0442\u043e \u0441\u0447\u0438\u0442\u0430\u0435\u0442\u0441\u044f \u0437\u0430 \u0436\u0443\u043b\u044c\u043d\u0438\u0447\u0435\u0441\u0442\u0432\u043e \u2014 \u043e\u043a\u0440\u0443\u0433\u043b\u044f\u0442\u044c \u0438 \u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u0442\u044c\u0441\u044f \u043f\u0440\u0438\u0451\u043c\u0430\u043c\u0438?","\u0412\u043e\u0432\u0441\u0435 \u043d\u0435\u0442. \u0420\u0430\u0437\u0431\u0438\u0435\u043d\u0438\u0435 \u043d\u0430 \u0447\u0430\u0441\u0442\u0438, \u043e\u043a\u0440\u0443\u0433\u043b\u0435\u043d\u0438\u0435 \u0438 \u043f\u0440\u0438\u0451\u043c\u044b \u0432\u0440\u043e\u0434\u0435 \u0434\u043e\u043f\u043e\u043b\u043d\u0435\u043d\u0438\u0439 \u2014 \u0438\u043c\u0435\u043d\u043d\u043e \u0442\u0430\u043a \u0438 \u0440\u0430\u0431\u043e\u0442\u0430\u044e\u0442 \u0431\u044b\u0441\u0442\u0440\u044b\u0435 \u0441\u0447\u0451\u0442\u0447\u0438\u043a\u0438 \u0432 \u0443\u043c\u0435. \u0426\u0435\u043b\u044c \u044d\u0442\u043e \u0432\u0435\u0440\u043d\u044b\u0439 \u043e\u0442\u0432\u0435\u0442 \u0431\u044b\u0441\u0442\u0440\u043e, \u0430 \u043d\u0435 \u043a\u043e\u043d\u043a\u0440\u0435\u0442\u043d\u044b\u0439 \u0441\u043f\u043e\u0441\u043e\u0431."],["\u0427\u0435\u043c \u044d\u0442\u043e \u043e\u0442\u043b\u0438\u0447\u0430\u0435\u0442\u0441\u044f \u043e\u0442 \u0441\u0447\u0451\u0442\u0430 \u043d\u0430 \u0431\u0443\u043c\u0430\u0433\u0435 \u0438\u043b\u0438 \u043a\u0430\u043b\u044c\u043a\u0443\u043b\u044f\u0442\u043e\u0440\u0435?","\u0411\u0443\u043c\u0430\u0433\u0430 \u0438 \u043a\u0430\u043b\u044c\u043a\u0443\u043b\u044f\u0442\u043e\u0440 \u0431\u0435\u0440\u0443\u0442 \u0445\u0440\u0430\u043d\u0435\u043d\u0438\u0435 \u043d\u0430 \u0441\u0435\u0431\u044f, \u0430 \u0437\u0434\u0435\u0441\u044c \u0447\u0438\u0441\u043b\u0430 \u0438 \u043f\u0440\u043e\u043c\u0435\u0436\u0443\u0442\u043e\u0447\u043d\u044b\u0435 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442\u044b \u043d\u0430\u0434\u043e \u0434\u0435\u0440\u0436\u0430\u0442\u044c \u0432 \u0433\u043e\u043b\u043e\u0432\u0435 \u2014 \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u044d\u0442\u043e \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u0435 \u043d\u0430 \u0440\u0430\u0431\u043e\u0447\u0443\u044e \u043f\u0430\u043c\u044f\u0442\u044c \u0438 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c, \u0430 \u043d\u0435 \u043f\u0440\u043e\u0441\u0442\u043e \u043f\u0440\u043e\u0432\u0435\u0440\u043a\u0430 \u0430\u0440\u0438\u0444\u043c\u0435\u0442\u0438\u043a\u0438."]],variants:"\u0412\u0430\u0440\u0438\u0430\u043d\u0442\u044b \u043c\u0435\u043d\u044f\u044e\u0442 \u043d\u0430\u0431\u043e\u0440 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0439 (\u0442\u043e\u043b\u044c\u043a\u043e \u0441\u043b\u043e\u0436\u0435\u043d\u0438\u0435 \u0438 \u0432\u044b\u0447\u0438\u0442\u0430\u043d\u0438\u0435 \u0438\u043b\u0438 \u0435\u0449\u0451 \u0443\u043c\u043d\u043e\u0436\u0435\u043d\u0438\u0435 \u0438 \u0434\u0435\u043b\u0435\u043d\u0438\u0435), \u0434\u043b\u0438\u043d\u0443 \u0446\u0435\u043f\u043e\u0447\u043a\u0438, \u0434\u0438\u0430\u043f\u0430\u0437\u043e\u043d \u0447\u0438\u0441\u0435\u043b \u0438 \u0445\u0430\u0440\u0430\u043a\u0442\u0435\u0440 \u0442\u0430\u0439\u043c\u0435\u0440\u0430 \u2014 \u0444\u0438\u043a\u0441\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u044b\u0439 \u0438\u043b\u0438 \u0443\u0441\u043a\u043e\u0440\u044f\u044e\u0449\u0438\u0439\u0441\u044f \u043f\u043e \u0445\u043e\u0434\u0443. \u0418\u0437 \u0440\u043e\u0434\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0445 \u0434\u0438\u0441\u0446\u0438\u043f\u043b\u0438\u043d \u2014 \u043c\u0435\u043d\u0442\u0430\u043b\u044c\u043d\u044b\u0439 \u0441\u0447\u0451\u0442 \u043d\u0430 \u0441\u043e\u0440\u043e\u0431\u0430\u043d\u0435, \u0444\u043b\u0435\u0448-\u0430\u043d\u0434\u0437\u0430\u043d \u0438 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u043d\u044b\u0435 \u043f\u0440\u043e\u0433\u043e\u043d\u044b \u0442\u0430\u0431\u043b\u0438\u0446\u044b \u0443\u043c\u043d\u043e\u0436\u0435\u043d\u0438\u044f."},en:{about:"Counter: Math is a timed mental-arithmetic drill. The screen shows a quick chain of operations or a single problem, and your job is to compute the answer in your head and enter it before the clock runs out, then immediately move on to the next one.",benefit:"It trains working memory and processing speed for numbers \u2014 holding intermediate results in mind, applying the right operation, and retrieving basic number facts fast and accurately under time pressure.",history:"Mental calculation is one of the oldest learned skills, taught for centuries through the abacus and soroban and through everyday market and trade arithmetic. Speed-calculation systems such as the Japanese mental abacus (and its flash anzan offshoot), Vedic mathematics and the Trachtenberg method later formalised tricks for doing it faster, and timed arithmetic drills like this one are the digital descendant of that long tradition.",creator:"There is no single inventor \u2014 mental arithmetic is a generic exercise that belongs to the broad tradition of abacus and school-arithmetic training. Named systems exist around it: the Trachtenberg method was devised by Jakow Trachtenberg in the mid-20th century, and Vedic mathematics was popularised by Bharati Krishna Tirtha in a book published in 1965, but the underlying skill predates all of them.",methods:"Don't sub-vocalise digit by digit; learn to chunk and round (treat 48 as 50 minus 2). Memorise the building blocks \u2014 small multiplication tables, complements to 10 and 100 \u2014 so retrieval is automatic. Push for a comfortable speed first, then trim it; accuracy under mild time pressure beats reckless guessing.",duration:"Short, frequent sessions work best: 5 to 10 minutes a day beats one long weekly grind. Stop when accuracy starts to slip, since fatigue trains sloppy habits rather than fluency.",research:"The solid finding is the obvious one \u2014 practise mental arithmetic and you get measurably faster and more accurate at mental arithmetic, and working memory is reliably correlated with arithmetic skill. The bigger claims are weaker: broad transfer to general intelligence or unrelated everyday tasks is largely unproven, brain-training games have repeatedly failed to show far transfer in well-controlled studies, and even mental-abacus research disagrees on whether it lifts working memory itself. Treat any '+IQ' promise with caution.",rec:"Keep the difficulty just past comfortable \u2014 problems you solve in a few seconds with effort \u2014 and practise daily in short bursts rather than rare marathons.",faq:[["Will this make me smarter or raise my IQ?","Realistically, no. You will get noticeably better and faster at mental arithmetic, but there is little reliable evidence that it boosts general intelligence or unrelated skills, so we don't promise that."],["Is it cheating to round numbers or use shortcuts?","Not at all \u2014 chunking, rounding and learned tricks like complements are exactly how fast mental calculators work. The goal is the correct answer quickly, not a particular method."],["How is this different from doing math on paper or a calculator?","Paper and calculators offload the storage; here you have to hold the numbers and partial results in your head, which is what makes it a working-memory and speed exercise rather than just an arithmetic test."]],variants:"Variants change the operations (addition and subtraction only, or full multiplication and division), the length of the chain, the number ranges, and whether the clock is fixed or speeds up as you go. Related disciplines include soroban-based mental abacus, flash anzan and rapid times-table drills."},es:{about:"Counter: Math es un ejercicio de c\xe1lculo mental contrarreloj. La pantalla muestra una cadena r\xe1pida de operaciones o un \xfanico problema, y tu tarea es calcular la respuesta de cabeza e introducirla antes de que se acabe el tiempo, para pasar de inmediato a la siguiente.",benefit:"Entrena la memoria de trabajo y la velocidad de procesamiento con n\xfameros: retener resultados intermedios en la mente, aplicar la operaci\xf3n correcta y recuperar hechos num\xe9ricos b\xe1sicos con rapidez y precisi\xf3n bajo presi\xf3n de tiempo.",history:"El c\xe1lculo mental es una de las destrezas aprendidas m\xe1s antiguas, ense\xf1ada durante siglos mediante el \xe1baco y el soroban y a trav\xe9s de la aritm\xe9tica cotidiana del mercado y el comercio. Sistemas de c\xe1lculo r\xe1pido como el \xe1baco mental japon\xe9s (y su derivado flash anzan), las matem\xe1ticas v\xe9dicas y el m\xe9todo Trachtenberg formalizaron despu\xe9s trucos para hacerlo m\xe1s r\xe1pido, y los ejercicios de aritm\xe9tica contrarreloj como este son el descendiente digital de esa larga tradici\xf3n.",creator:"No hay un \xfanico inventor: el c\xe1lculo mental es un ejercicio gen\xe9rico que pertenece a la amplia tradici\xf3n del \xe1baco y la aritm\xe9tica escolar. Existen sistemas con nombre propio a su alrededor: el m\xe9todo Trachtenberg fue ideado por Jakow Trachtenberg a mediados del siglo XX, y las matem\xe1ticas v\xe9dicas fueron popularizadas por Bharati Krishna Tirtha en un libro publicado en 1965, pero la destreza de fondo es anterior a todos ellos.",methods:"No subvocalices d\xedgito a d\xedgito; aprende a agrupar y redondear (trata el 48 como 50 menos 2). Memoriza los componentes b\xe1sicos \u2014las tablas de multiplicar peque\xf1as, los complementos a 10 y a 100\u2014 para que la recuperaci\xf3n sea autom\xe1tica. Busca primero una velocidad c\xf3moda y luego rec\xf3rtala; la precisi\xf3n bajo una presi\xf3n de tiempo moderada vale m\xe1s que adivinar a lo loco.",duration:"Las sesiones cortas y frecuentes funcionan mejor: de 5 a 10 minutos al d\xeda superan a una sola sesi\xf3n larga semanal. Para cuando la precisi\xf3n empiece a fallar, porque la fatiga entrena h\xe1bitos descuidados en lugar de soltura.",research:"El hallazgo s\xf3lido es el obvio: practica el c\xe1lculo mental y mejorar\xe1s de forma medible en velocidad y precisi\xf3n en el c\xe1lculo mental, y la memoria de trabajo est\xe1 fiablemente correlacionada con la habilidad aritm\xe9tica. Las afirmaciones m\xe1s grandes son m\xe1s d\xe9biles: la transferencia amplia a la inteligencia general o a tareas cotidianas no relacionadas est\xe1 en gran medida sin demostrar, los juegos de entrenamiento mental han fallado repetidamente en mostrar transferencia lejana en estudios bien controlados, e incluso la investigaci\xf3n sobre el \xe1baco mental discrepa sobre si eleva la propia memoria de trabajo. Toma con cautela cualquier promesa de '+CI'.",rec:"Mant\xe9n la dificultad justo por encima de lo c\xf3modo \u2014problemas que resuelvas en unos segundos con esfuerzo\u2014 y practica a diario en tandas cortas en lugar de hacer maratones espor\xe1dicos.",faq:[["\xbfEsto me har\xe1 m\xe1s inteligente o me subir\xe1 el CI?","Siendo realistas, no. Mejorar\xe1s notablemente y ser\xe1s m\xe1s r\xe1pido en el c\xe1lculo mental, pero hay poca evidencia fiable de que potencie la inteligencia general o habilidades no relacionadas, as\xed que no lo prometemos."],["\xbfEs hacer trampa redondear n\xfameros o usar atajos?","Para nada: agrupar, redondear y los trucos aprendidos como los complementos son exactamente como trabajan los calculistas r\xe1pidos. El objetivo es la respuesta correcta con rapidez, no un m\xe9todo concreto."],["\xbfEn qu\xe9 se diferencia esto de hacer cuentas en papel o con calculadora?","El papel y las calculadoras descargan el almacenamiento; aqu\xed tienes que retener los n\xfameros y los resultados parciales en la cabeza, que es lo que lo convierte en un ejercicio de memoria de trabajo y velocidad en lugar de una simple prueba de aritm\xe9tica."]],variants:"Las variantes cambian las operaciones (solo sumas y restas, o multiplicaci\xf3n y divisi\xf3n completas), la longitud de la cadena, los rangos num\xe9ricos y si el reloj es fijo o se acelera a medida que avanzas. Entre las disciplinas afines est\xe1n el \xe1baco mental basado en el soroban, el flash anzan y los ejercicios r\xe1pidos de tablas de multiplicar."},de:{about:"Counter: Math ist eine Kopfrechen\xfcbung auf Zeit. Der Bildschirm zeigt eine schnelle Kette von Rechenschritten oder eine einzelne Aufgabe, und deine Aufgabe ist es, das Ergebnis im Kopf auszurechnen und einzugeben, bevor die Uhr abl\xe4uft \u2014 und dann sofort zur n\xe4chsten \xfcberzugehen.",benefit:"Sie trainiert Arbeitsged\xe4chtnis und Verarbeitungsgeschwindigkeit f\xfcr Zahlen \u2014 Zwischenergebnisse im Kopf zu behalten, die richtige Rechenart anzuwenden und grundlegende Zahlenfakten unter Zeitdruck schnell und korrekt abzurufen.",history:"Kopfrechnen geh\xf6rt zu den \xe4ltesten erlernten Fertigkeiten und wurde \xfcber Jahrhunderte mit dem Abakus und dem Soroban sowie durch das allt\xe4gliche Markt- und Handelsrechnen gelehrt. Schnellrechensysteme wie der japanische mentale Abakus (und sein Flash-Anzan-Ableger), die vedische Mathematik und die Trachtenberg-Methode formalisierten sp\xe4ter Kniffe, um es schneller zu tun, und Rechen\xfcbungen auf Zeit wie diese sind der digitale Nachkomme dieser langen Tradition.",creator:"Es gibt keinen einzelnen Erfinder \u2014 Kopfrechnen ist eine allgemeine \xdcbung, die zur breiten Tradition des Abakus- und Schulrechentrainings geh\xf6rt. Drumherum existieren benannte Systeme: Die Trachtenberg-Methode wurde von Jakow Trachtenberg Mitte des 20. Jahrhunderts ersonnen, und die vedische Mathematik wurde von Bharati Krishna Tirtha in einem 1965 ver\xf6ffentlichten Buch popul\xe4r gemacht, doch die zugrunde liegende Fertigkeit ist \xe4lter als sie alle.",methods:"Sprich nicht Ziffer f\xfcr Ziffer innerlich mit; lerne, in Brocken zu denken und zu runden (behandle 48 als 50 minus 2). Verinnerliche die Bausteine \u2014 kleine Einmaleinsreihen, Erg\xe4nzungen zu 10 und 100 \u2014, damit der Abruf automatisch l\xe4uft. Strebe zuerst ein bequemes Tempo an und k\xfcrze es dann; Genauigkeit unter mildem Zeitdruck schl\xe4gt waghalsiges Raten.",duration:"Kurze, h\xe4ufige Sitzungen funktionieren am besten: 5 bis 10 Minuten am Tag schlagen ein langes w\xf6chentliches Durchackern. H\xf6r auf, sobald die Genauigkeit nachzulassen beginnt, denn Erm\xfcdung trainiert schludrige Gewohnheiten statt Sicherheit.",research:"Der belastbare Befund ist der naheliegende \u2014 \xfcbe Kopfrechnen, und du wirst beim Kopfrechnen messbar schneller und genauer, und das Arbeitsged\xe4chtnis korreliert zuverl\xe4ssig mit der Rechenfertigkeit. Die gr\xf6\xdferen Behauptungen sind schw\xe4cher: Ein breiter \xdcbertrag auf allgemeine Intelligenz oder unverwandte Alltagsaufgaben ist weitgehend unbewiesen, Gehirntrainingsspiele haben in gut kontrollierten Studien wiederholt keinen Ferntransfer gezeigt, und selbst die Forschung zum mentalen Abakus ist sich uneins, ob er das Arbeitsged\xe4chtnis selbst hebt. Begegne jedem '+IQ'-Versprechen mit Vorsicht.",rec:"Halte den Schwierigkeitsgrad knapp \xfcber bequem \u2014 Aufgaben, die du mit Anstrengung in wenigen Sekunden l\xf6st \u2014 und \xfcbe t\xe4glich in kurzen St\xf6\xdfen statt in seltenen Marathons.",faq:[["Macht mich das schlauer oder steigert es meinen IQ?","Realistisch betrachtet nein. Du wirst beim Kopfrechnen sp\xfcrbar besser und schneller, aber es gibt kaum verl\xe4ssliche Belege daf\xfcr, dass es die allgemeine Intelligenz oder unverwandte Fertigkeiten steigert, also versprechen wir das nicht."],["Ist es Schummeln, Zahlen zu runden oder Abk\xfcrzungen zu nutzen?","Ganz und gar nicht \u2014 in Brocken zerlegen, runden und gelernte Kniffe wie Erg\xe4nzungen sind genau die Art, wie schnelle Kopfrechner arbeiten. Das Ziel ist die richtige Antwort, und zwar schnell, nicht eine bestimmte Methode."],["Wie unterscheidet sich das vom Rechnen auf Papier oder mit dem Taschenrechner?","Papier und Taschenrechner nehmen dir das Speichern ab; hier musst du die Zahlen und Teilergebnisse im Kopf halten, und genau das macht es zu einer Arbeitsged\xe4chtnis- und Tempo\xfcbung statt blo\xdf zu einem Rechentest."]],variants:"Varianten ver\xe4ndern die Rechenarten (nur Addition und Subtraktion oder das volle Multiplizieren und Dividieren), die L\xe4nge der Kette, die Zahlenbereiche und ob die Uhr fest bleibt oder im Verlauf schneller wird. Verwandte Disziplinen sind der soroban-basierte mentale Abakus, Flash Anzan und schnelle Einmaleins-\xdcbungen."},pt:{about:"Counter: Math \xe9 um exerc\xedcio cronometrado de c\xe1lculo mental. A tela mostra uma cadeia r\xe1pida de opera\xe7\xf5es ou um \xfanico problema, e sua miss\xe3o \xe9 calcular a resposta de cabe\xe7a e digit\xe1-la antes que o tempo acabe, passando logo em seguida para o pr\xf3ximo.",benefit:"Treina a mem\xf3ria de trabalho e a velocidade de processamento para n\xfameros \u2014 manter resultados intermedi\xe1rios na cabe\xe7a, aplicar a opera\xe7\xe3o certa e recuperar fatos num\xe9ricos b\xe1sicos com rapidez e precis\xe3o sob press\xe3o de tempo.",history:"O c\xe1lculo mental \xe9 uma das habilidades aprendidas mais antigas, ensinada por s\xe9culos pelo \xe1baco e pelo soroban e pela aritm\xe9tica cotidiana de mercado e com\xe9rcio. Sistemas de c\xe1lculo r\xe1pido como o \xe1baco mental japon\xeas (e seu desdobramento, o flash anzan), a matem\xe1tica v\xe9dica e o m\xe9todo Trachtenberg mais tarde formalizaram truques para faz\xea-lo mais depressa, e exerc\xedcios cronometrados de aritm\xe9tica como este s\xe3o o descendente digital dessa longa tradi\xe7\xe3o.",creator:"N\xe3o h\xe1 um \xfanico inventor \u2014 a aritm\xe9tica mental \xe9 um exerc\xedcio gen\xe9rico que pertence \xe0 ampla tradi\xe7\xe3o do \xe1baco e da aritm\xe9tica escolar. Existem sistemas com nome ao seu redor: o m\xe9todo Trachtenberg foi concebido por Jakow Trachtenberg em meados do s\xe9culo XX, e a matem\xe1tica v\xe9dica foi popularizada por Bharati Krishna Tirtha em um livro publicado em 1965, mas a habilidade subjacente antecede todos eles.",methods:"N\xe3o subvocalize d\xedgito por d\xedgito; aprenda a agrupar e arredondar (trate 48 como 50 menos 2). Memorize os blocos de constru\xe7\xe3o \u2014 pequenas tabuadas, complementos para 10 e 100 \u2014 para que a recupera\xe7\xe3o seja autom\xe1tica. Busque primeiro uma velocidade confort\xe1vel e depois apare o tempo; precis\xe3o sob leve press\xe3o de tempo vale mais do que chutes imprudentes.",duration:"Sess\xf5es curtas e frequentes funcionam melhor: 5 a 10 minutos por dia batem uma longa maratona semanal. Pare quando a precis\xe3o come\xe7ar a escorregar, pois o cansa\xe7o treina h\xe1bitos desleixados em vez de flu\xeancia.",research:"O achado s\xf3lido \xe9 o \xf3bvio \u2014 pratique aritm\xe9tica mental e voc\xea fica mensuravelmente mais r\xe1pido e mais preciso em aritm\xe9tica mental, e a mem\xf3ria de trabalho est\xe1 confiavelmente correlacionada com a habilidade aritm\xe9tica. As afirma\xe7\xf5es maiores s\xe3o mais fracas: a transfer\xeancia ampla para a intelig\xeancia geral ou para tarefas cotidianas n\xe3o relacionadas \xe9 em grande parte n\xe3o comprovada, jogos de treino cerebral falharam repetidamente em mostrar transfer\xeancia distante em estudos bem controlados, e at\xe9 a pesquisa sobre o \xe1baco mental discorda sobre se ele eleva a pr\xf3pria mem\xf3ria de trabalho. Trate qualquer promessa de '+QI' com cautela.",rec:"Mantenha a dificuldade logo acima do confort\xe1vel \u2014 problemas que voc\xea resolve em alguns segundos com esfor\xe7o \u2014 e pratique diariamente em rajadas curtas, n\xe3o em maratonas raras.",faq:[["Isto vai me deixar mais inteligente ou elevar meu QI?","Realisticamente, n\xe3o. Voc\xea ficar\xe1 bem melhor e mais r\xe1pido em aritm\xe9tica mental, mas h\xe1 pouca evid\xeancia confi\xe1vel de que isso eleve a intelig\xeancia geral ou habilidades n\xe3o relacionadas, ent\xe3o n\xe3o prometemos isso."],["\xc9 trapa\xe7a arredondar n\xfameros ou usar atalhos?","De forma alguma \u2014 agrupar, arredondar e truques aprendidos como os complementos s\xe3o exatamente como trabalham os calculadores mentais r\xe1pidos. O objetivo \xe9 a resposta correta com rapidez, n\xe3o um m\xe9todo espec\xedfico."],["Qual a diferen\xe7a entre isto e fazer contas no papel ou na calculadora?","Papel e calculadora terceirizam o armazenamento; aqui voc\xea precisa manter os n\xfameros e os resultados parciais na cabe\xe7a, o que \xe9 o que torna isto um exerc\xedcio de mem\xf3ria de trabalho e velocidade, e n\xe3o apenas um teste de aritm\xe9tica."]],variants:"As variantes mudam as opera\xe7\xf5es (s\xf3 adi\xe7\xe3o e subtra\xe7\xe3o, ou multiplica\xe7\xe3o e divis\xe3o completas), o comprimento da cadeia, as faixas num\xe9ricas e se o rel\xf3gio \xe9 fixo ou acelera conforme voc\xea avan\xe7a. Disciplinas relacionadas incluem o \xe1baco mental baseado no soroban, o flash anzan e os exerc\xedcios r\xe1pidos de tabuada."},hi:{about:"Counter: Math \u0938\u092e\u092f-\u092c\u0926\u094d\u0927 \u092e\u093e\u0928\u0938\u093f\u0915-\u0917\u0923\u093f\u0924 \u0915\u0940 \u090f\u0915 \u0915\u0938\u0930\u0924 \u0939\u0948\u0964 \u0938\u094d\u0915\u094d\u0930\u0940\u0928 \u092a\u0930 \u0938\u0902\u0915\u094d\u0930\u093f\u092f\u093e\u0913\u0902 \u0915\u0940 \u090f\u0915 \u0924\u0947\u091c\u093c \u0936\u094d\u0930\u0943\u0902\u0916\u0932\u093e \u092f\u093e \u090f\u0915 \u0905\u0915\u0947\u0932\u093e \u0938\u0935\u093e\u0932 \u0926\u093f\u0916\u0924\u093e \u0939\u0948, \u0914\u0930 \u0906\u092a\u0915\u093e \u0915\u093e\u092e \u0939\u0948 \u0918\u0921\u093c\u0940 \u0916\u093c\u0924\u094d\u092e \u0939\u094b\u0928\u0947 \u0938\u0947 \u092a\u0939\u0932\u0947 \u092e\u0928 \u0939\u0940 \u092e\u0928 \u091c\u0935\u093e\u092c \u0928\u093f\u0915\u093e\u0932\u0915\u0930 \u0926\u0930\u094d\u091c \u0915\u0930\u0928\u093e, \u092b\u093f\u0930 \u092b\u093c\u094c\u0930\u0928 \u0905\u0917\u0932\u0947 \u092a\u0930 \u092c\u0922\u093c \u091c\u093e\u0928\u093e\u0964",benefit:"\u092f\u0939 \u0938\u0902\u0916\u094d\u092f\u093e\u0913\u0902 \u0915\u0947 \u0932\u093f\u090f \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932 \u0938\u094d\u092e\u0943\u0924\u093f (\u0935\u0930\u094d\u0915\u093f\u0902\u0917 \u092e\u0947\u092e\u0930\u0940) \u0914\u0930 \u092a\u094d\u0930\u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0917\u0924\u093f \u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0930\u093e\u0924\u093e \u0939\u0948 \u2014 \u092c\u0940\u091a \u0915\u0947 \u0928\u0924\u0940\u091c\u094b\u0902 \u0915\u094b \u0926\u093f\u092e\u093e\u0917 \u092e\u0947\u0902 \u0925\u093e\u092e\u0947 \u0930\u0916\u0928\u093e, \u0938\u0939\u0940 \u0938\u0902\u0915\u094d\u0930\u093f\u092f\u093e \u0932\u0917\u093e\u0928\u093e, \u0914\u0930 \u0938\u092e\u092f \u0915\u0947 \u0926\u092c\u093e\u0935 \u092e\u0947\u0902 \u092c\u0941\u0928\u093f\u092f\u093e\u0926\u0940 \u0938\u0902\u0916\u094d\u092f\u093e-\u0924\u0925\u094d\u092f\u094b\u0902 \u0915\u094b \u0924\u0947\u091c\u093c\u0940 \u0935 \u0938\u091f\u0940\u0915\u0924\u093e \u0938\u0947 \u092f\u093e\u0926 \u0938\u0947 \u0928\u093f\u0915\u093e\u0932\u0928\u093e\u0964",history:"\u092e\u093e\u0928\u0938\u093f\u0915 \u0917\u0923\u0928\u093e \u0938\u092c\u0938\u0947 \u092a\u0941\u0930\u093e\u0928\u0947 \u0938\u0940\u0916\u0947 \u0939\u0941\u090f \u0915\u094c\u0936\u0932\u094b\u0902 \u092e\u0947\u0902 \u0938\u0947 \u090f\u0915 \u0939\u0948, \u091c\u093f\u0938\u0947 \u0938\u0926\u093f\u092f\u094b\u0902 \u0924\u0915 \u0905\u092c\u0947\u0915\u0938 \u0914\u0930 \u0938\u094b\u0930\u094b\u092c\u0928 \u0915\u0947 \u091c\u093c\u0930\u093f\u090f \u0924\u0925\u093e \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0947 \u092c\u093e\u091c\u093c\u093e\u0930 \u0914\u0930 \u0935\u094d\u092f\u093e\u092a\u093e\u0930 \u0915\u0947 \u0905\u0902\u0915\u0917\u0923\u093f\u0924 \u0915\u0947 \u091c\u093c\u0930\u093f\u090f \u0938\u093f\u0916\u093e\u092f\u093e \u091c\u093e\u0924\u093e \u0930\u0939\u093e\u0964 \u091c\u093e\u092a\u093e\u0928\u0940 \u092e\u093e\u0928\u0938\u093f\u0915 \u0905\u092c\u0947\u0915\u0938 (\u0914\u0930 \u0907\u0938\u0915\u0940 \u092b\u093c\u094d\u0932\u0948\u0936 \u0905\u0902\u091c\u093c\u093e\u0928 \u0936\u093e\u0916\u093e), \u0935\u0948\u0926\u093f\u0915 \u0917\u0923\u093f\u0924 \u0914\u0930 \u091f\u094d\u0930\u0947\u091a\u0947\u0928\u092c\u0930\u094d\u0917 \u092a\u0926\u094d\u0927\u0924\u093f \u091c\u0948\u0938\u0940 \u0924\u0947\u091c\u093c-\u0917\u0923\u0928\u093e \u092a\u094d\u0930\u0923\u093e\u0932\u093f\u092f\u094b\u0902 \u0928\u0947 \u092c\u093e\u0926 \u092e\u0947\u0902 \u0907\u0938\u0947 \u0914\u0930 \u0924\u0947\u091c\u093c \u0915\u0930\u0928\u0947 \u0915\u0940 \u0924\u0930\u0915\u0940\u092c\u094b\u0902 \u0915\u094b \u0914\u092a\u091a\u093e\u0930\u093f\u0915 \u0930\u0942\u092a \u0926\u093f\u092f\u093e, \u0914\u0930 \u0907\u0938 \u091c\u0948\u0938\u0940 \u0938\u092e\u092f-\u092c\u0926\u094d\u0927 \u0905\u0902\u0915\u0917\u0923\u093f\u0924 \u0915\u0938\u0930\u0924\u0947\u0902 \u0909\u0938\u0940 \u0932\u0902\u092c\u0940 \u092a\u0930\u0902\u092a\u0930\u093e \u0915\u0940 \u0921\u093f\u091c\u093f\u091f\u0932 \u0938\u0902\u0924\u093e\u0928 \u0939\u0948\u0902\u0964",creator:"\u0907\u0938\u0915\u093e \u0915\u094b\u0908 \u090f\u0915\u092e\u093e\u0924\u094d\u0930 \u0906\u0935\u093f\u0937\u094d\u0915\u093e\u0930\u0915 \u0928\u0939\u0940\u0902 \u0939\u0948 \u2014 \u092e\u093e\u0928\u0938\u093f\u0915 \u0905\u0902\u0915\u0917\u0923\u093f\u0924 \u090f\u0915 \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u0915\u0938\u0930\u0924 \u0939\u0948 \u091c\u094b \u0905\u092c\u0947\u0915\u0938 \u0914\u0930 \u0938\u094d\u0915\u0942\u0932\u0940-\u0905\u0902\u0915\u0917\u0923\u093f\u0924 \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u0915\u0940 \u0935\u094d\u092f\u093e\u092a\u0915 \u092a\u0930\u0902\u092a\u0930\u093e \u0915\u093e \u0939\u093f\u0938\u094d\u0938\u093e \u0939\u0948\u0964 \u0907\u0938\u0915\u0947 \u0907\u0930\u094d\u0926-\u0917\u093f\u0930\u094d\u0926 \u0928\u093e\u092e\u0927\u093e\u0930\u0940 \u092a\u094d\u0930\u0923\u093e\u0932\u093f\u092f\u093e\u0901 \u091c\u093c\u0930\u0942\u0930 \u0939\u0948\u0902: \u091f\u094d\u0930\u0947\u091a\u0947\u0928\u092c\u0930\u094d\u0917 \u092a\u0926\u094d\u0927\u0924\u093f \u0915\u094b Jakow Trachtenberg \u0928\u0947 \u092c\u0940\u0938\u0935\u0940\u0902 \u0938\u0926\u0940 \u0915\u0947 \u092e\u0927\u094d\u092f \u092e\u0947\u0902 \u0930\u091a\u093e, \u0914\u0930 \u0935\u0948\u0926\u093f\u0915 \u0917\u0923\u093f\u0924 \u0915\u094b Bharati Krishna Tirtha \u0928\u0947 1965 \u092e\u0947\u0902 \u092a\u094d\u0930\u0915\u093e\u0936\u093f\u0924 \u090f\u0915 \u0915\u093f\u0924\u093e\u092c \u0915\u0947 \u091c\u093c\u0930\u093f\u090f \u0932\u094b\u0915\u092a\u094d\u0930\u093f\u092f \u0915\u093f\u092f\u093e, \u092e\u0917\u0930 \u0907\u0938\u0915\u093e \u092e\u0942\u0932 \u0915\u094c\u0936\u0932 \u0907\u0928 \u0938\u092c\u0938\u0947 \u092a\u0941\u0930\u093e\u0928\u093e \u0939\u0948\u0964",methods:"\u0905\u0902\u0915-\u0926\u0930-\u0905\u0902\u0915 \u092e\u0928 \u0939\u0940 \u092e\u0928 \u092e\u0924 \u092c\u0941\u0926\u092c\u0941\u0926\u093e\u0907\u090f; \u0917\u0941\u091a\u094d\u091b\u094b\u0902 \u092e\u0947\u0902 \u092c\u093e\u0901\u091f\u0928\u093e \u0914\u0930 \u0917\u094b\u0932\u093e\u0908 \u092e\u0947\u0902 \u0932\u093e\u0928\u093e (round) \u0938\u0940\u0916\u093f\u090f (48 \u0915\u094b 50 \u092e\u0947\u0902 \u0938\u0947 2 \u0918\u091f\u093e \u0939\u0941\u0906 \u092e\u093e\u0928\u093f\u090f)\u0964 \u092c\u0941\u0928\u093f\u092f\u093e\u0926\u0940 \u0907\u0915\u093e\u0907\u092f\u093e\u0901 \u0930\u091f \u0932\u0940\u091c\u093f\u090f \u2014 \u091b\u094b\u091f\u0947 \u092a\u0939\u093e\u0921\u093c\u0947, 10 \u0914\u0930 100 \u0915\u0947 \u092a\u0942\u0930\u0915 \u2014 \u0924\u093e\u0915\u093f \u092f\u093e\u0926 \u0938\u0947 \u0928\u093f\u0915\u093e\u0932\u0928\u093e \u0905\u092a\u0928\u0947-\u0906\u092a \u0939\u094b \u091c\u093e\u090f\u0964 \u092a\u0939\u0932\u0947 \u090f\u0915 \u0906\u0930\u093e\u092e\u0926\u0947\u0939 \u0917\u0924\u093f \u0939\u093e\u0938\u093f\u0932 \u0915\u0940\u091c\u093f\u090f, \u092b\u093f\u0930 \u0909\u0938\u0947 \u0915\u093e\u091f\u093f\u090f; \u0939\u0932\u094d\u0915\u0947 \u0938\u092e\u092f-\u0926\u092c\u093e\u0935 \u092e\u0947\u0902 \u0938\u091f\u0940\u0915\u0924\u093e \u0932\u093e\u092a\u0930\u0935\u093e\u0939 \u0905\u0902\u0926\u093e\u091c\u093c\u0947 \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u0939\u0948\u0964",duration:"\u091b\u094b\u091f\u0947, \u092c\u093e\u0930-\u092c\u093e\u0930 \u0915\u0947 \u0938\u0924\u094d\u0930 \u0938\u092c\u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u0930\u0939\u0924\u0947 \u0939\u0948\u0902: \u0930\u094b\u091c\u093c 5 \u0938\u0947 10 \u092e\u093f\u0928\u091f \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u090f\u0915 \u0932\u0902\u092c\u0940 \u092a\u093f\u0938\u093e\u0908 \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u0939\u0948\u0902\u0964 \u091c\u092c \u0938\u091f\u0940\u0915\u0924\u093e \u092b\u093f\u0938\u0932\u0928\u0947 \u0932\u0917\u0947 \u0924\u094b \u0930\u0941\u0915 \u091c\u093e\u0907\u090f, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u0925\u0915\u093e\u0928 \u0927\u093e\u0930\u093e\u092a\u094d\u0930\u0935\u093e\u0939 \u0928\u0939\u0940\u0902, \u092c\u0932\u094d\u0915\u093f \u0932\u093e\u092a\u0930\u0935\u093e\u0939 \u0906\u0926\u0924\u0947\u0902 \u0938\u093f\u0916\u093e\u0924\u0940 \u0939\u0948\u0964",research:"\u092a\u0941\u0916\u093c\u094d\u0924\u093e \u0928\u0924\u0940\u091c\u093e \u0935\u0939\u0940 \u0938\u094d\u092a\u0937\u094d\u091f \u0935\u093e\u0932\u093e \u0939\u0948 \u2014 \u092e\u093e\u0928\u0938\u093f\u0915 \u0905\u0902\u0915\u0917\u0923\u093f\u0924 \u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0940\u091c\u093f\u090f \u0914\u0930 \u0906\u092a \u092e\u093e\u0928\u0938\u093f\u0915 \u0905\u0902\u0915\u0917\u0923\u093f\u0924 \u092e\u0947\u0902 \u0928\u093e\u092a-\u0924\u094c\u0932\u0915\u0930 \u0924\u0947\u091c\u093c \u0935 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0938\u091f\u0940\u0915 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932 \u0938\u094d\u092e\u0943\u0924\u093f \u0915\u093e \u0905\u0902\u0915\u0917\u0923\u093f\u0924-\u0915\u094c\u0936\u0932 \u0938\u0947 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0938\u0939\u0938\u0902\u092c\u0902\u0927 \u0939\u0948\u0964 \u092c\u0921\u093c\u0947 \u0926\u093e\u0935\u0947 \u0915\u092e\u091c\u093c\u094b\u0930 \u0939\u0948\u0902: \u0906\u092e \u092c\u0941\u0926\u094d\u0927\u093f \u092f\u093e \u0905\u0938\u0902\u092c\u0902\u0927\u093f\u0924 \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0947 \u0915\u093e\u092e\u094b\u0902 \u0924\u0915 \u0935\u094d\u092f\u093e\u092a\u0915 \u0939\u0938\u094d\u0924\u093e\u0902\u0924\u0930\u0923 \u0915\u093e\u092b\u093c\u0940 \u0939\u0926 \u0924\u0915 \u0905\u0938\u093e\u092c\u093f\u0924 \u0939\u0948, \u0938\u0941\u0928\u093f\u092f\u0902\u0924\u094d\u0930\u093f\u0924 \u0905\u0927\u094d\u092f\u092f\u0928\u094b\u0902 \u092e\u0947\u0902 \u0926\u093f\u092e\u093e\u0917\u0940 \u0915\u0938\u0930\u0924 \u0935\u093e\u0932\u0947 \u0916\u0947\u0932 \u092c\u093e\u0930-\u092c\u093e\u0930 \u0926\u0942\u0930-\u0939\u0938\u094d\u0924\u093e\u0902\u0924\u0930\u0923 \u0926\u093f\u0916\u093e\u0928\u0947 \u092e\u0947\u0902 \u0928\u093e\u0915\u093e\u092e \u0930\u0939\u0947 \u0939\u0948\u0902, \u0914\u0930 \u092e\u093e\u0928\u0938\u093f\u0915-\u0905\u092c\u0947\u0915\u0938 \u0936\u094b\u0927 \u0924\u0915 \u0907\u0938 \u092c\u093e\u0924 \u092a\u0930 \u090f\u0915\u092e\u0924 \u0928\u0939\u0940\u0902 \u0915\u093f \u092f\u0939 \u0916\u0941\u0926 \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932 \u0938\u094d\u092e\u0943\u0924\u093f \u0915\u094b \u092c\u0922\u093c\u093e\u0924\u093e \u0939\u0948 \u092f\u093e \u0928\u0939\u0940\u0902\u0964 \u0915\u093f\u0938\u0940 \u092d\u0940 '+IQ' \u0935\u093e\u0932\u0947 \u0935\u093e\u0926\u0947 \u0915\u094b \u0938\u093e\u0935\u0927\u093e\u0928\u0940 \u0938\u0947 \u0932\u0940\u091c\u093f\u090f\u0964",rec:"\u0915\u0920\u093f\u0928\u093e\u0908 \u0915\u094b \u0906\u0930\u093e\u092e\u0926\u0947\u0939 \u0938\u0947 \u092c\u0938 \u091c\u093c\u0930\u093e \u0906\u0917\u0947 \u0930\u0916\u093f\u090f \u2014 \u0910\u0938\u0947 \u0938\u0935\u093e\u0932 \u091c\u093f\u0928\u094d\u0939\u0947\u0902 \u0906\u092a \u0925\u094b\u0921\u093c\u0940 \u092e\u0947\u0939\u0928\u0924 \u0938\u0947 \u0915\u0941\u091b \u0939\u0940 \u0938\u0947\u0915\u0902\u0921 \u092e\u0947\u0902 \u0939\u0932 \u0915\u0930 \u0932\u0947\u0902 \u2014 \u0914\u0930 \u0915\u092d\u0940-\u0915\u092d\u093e\u0930 \u0915\u0947 \u092e\u0948\u0930\u093e\u0925\u0928 \u0915\u0947 \u092c\u091c\u093e\u092f \u0930\u094b\u091c\u093c \u091b\u094b\u091f\u0947-\u091b\u094b\u091f\u0947 \u0926\u094c\u0930 \u092e\u0947\u0902 \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0940\u091c\u093f\u090f\u0964",faq:[["\u0915\u094d\u092f\u093e \u092f\u0939 \u092e\u0941\u091d\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0939\u094b\u0936\u093f\u092f\u093e\u0930 \u092c\u0928\u093e \u0926\u0947\u0917\u093e \u092f\u093e \u092e\u0947\u0930\u093e IQ \u092c\u0922\u093c\u093e \u0926\u0947\u0917\u093e?","\u0939\u0915\u093c\u0940\u0915\u093c\u0924 \u092e\u0947\u0902, \u0928\u0939\u0940\u0902\u0964 \u0906\u092a \u092e\u093e\u0928\u0938\u093f\u0915 \u0905\u0902\u0915\u0917\u0923\u093f\u0924 \u092e\u0947\u0902 \u0938\u093e\u092b\u093c \u0924\u094c\u0930 \u092a\u0930 \u092c\u0947\u0939\u0924\u0930 \u0914\u0930 \u0924\u0947\u091c\u093c \u0939\u094b \u091c\u093e\u090f\u0901\u0917\u0947, \u092e\u0917\u0930 \u0907\u0938\u0915\u093e \u0915\u094b\u0908 \u0916\u093e\u0938 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0938\u092c\u0942\u0924 \u0928\u0939\u0940\u0902 \u0915\u093f \u092f\u0939 \u0906\u092e \u092c\u0941\u0926\u094d\u0927\u093f \u092f\u093e \u0905\u0938\u0902\u092c\u0902\u0927\u093f\u0924 \u0915\u094c\u0936\u0932\u094b\u0902 \u0915\u094b \u092c\u0922\u093c\u093e\u0924\u093e \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0939\u092e \u0935\u0939 \u0935\u093e\u0926\u093e \u0928\u0939\u0940\u0902 \u0915\u0930\u0924\u0947\u0964"],["\u0938\u0902\u0916\u094d\u092f\u093e\u0913\u0902 \u0915\u094b \u0917\u094b\u0932\u093e\u0908 \u092e\u0947\u0902 \u0932\u093e\u0928\u093e \u092f\u093e \u0936\u0949\u0930\u094d\u091f\u0915\u091f \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0915\u0930\u0928\u093e \u0915\u094d\u092f\u093e \u092c\u0947\u0908\u092e\u093e\u0928\u0940 \u0939\u0948?","\u092c\u093f\u0932\u094d\u0915\u0941\u0932 \u0928\u0939\u0940\u0902 \u2014 \u0917\u0941\u091a\u094d\u091b\u0947 \u092c\u0928\u093e\u0928\u093e, \u0917\u094b\u0932\u093e\u0908 \u092e\u0947\u0902 \u0932\u093e\u0928\u093e \u0914\u0930 \u092a\u0942\u0930\u0915\u094b\u0902 \u091c\u0948\u0938\u0940 \u0938\u0940\u0916\u0940 \u0939\u0941\u0908 \u0924\u0930\u0915\u0940\u092c\u0947\u0902 \u0920\u0940\u0915 \u0935\u0939\u0940 \u0939\u0948\u0902 \u091c\u0948\u0938\u0947 \u0924\u0947\u091c\u093c \u092e\u093e\u0928\u0938\u093f\u0915 \u0917\u0923\u0915 \u0915\u093e\u092e \u0915\u0930\u0924\u0947 \u0939\u0948\u0902\u0964 \u092e\u0915\u093c\u0938\u0926 \u091c\u0932\u094d\u0926\u0940 \u0938\u0947 \u0938\u0939\u0940 \u091c\u0935\u093e\u092c \u0939\u0948, \u0915\u094b\u0908 \u0916\u093e\u0938 \u0924\u0930\u0940\u0915\u093e \u0928\u0939\u0940\u0902\u0964"],["\u092f\u0939 \u0915\u093e\u0917\u091c\u093c \u092a\u0930 \u092f\u093e \u0915\u0948\u0932\u0915\u0941\u0932\u0947\u091f\u0930 \u0938\u0947 \u0917\u0923\u093f\u0924 \u0915\u0930\u0928\u0947 \u0938\u0947 \u0915\u0948\u0938\u0947 \u0905\u0932\u0917 \u0939\u0948?","\u0915\u093e\u0917\u091c\u093c \u0914\u0930 \u0915\u0948\u0932\u0915\u0941\u0932\u0947\u091f\u0930 \u092d\u0902\u0921\u093e\u0930\u0923 \u0915\u093e \u092c\u094b\u091d \u0909\u0924\u093e\u0930 \u0926\u0947\u0924\u0947 \u0939\u0948\u0902; \u092f\u0939\u093e\u0901 \u0906\u092a\u0915\u094b \u0938\u0902\u0916\u094d\u092f\u093e\u090f\u0901 \u0914\u0930 \u0906\u0902\u0936\u093f\u0915 \u0928\u0924\u0940\u091c\u0947 \u0905\u092a\u0928\u0947 \u0926\u093f\u092e\u093e\u0917 \u092e\u0947\u0902 \u0925\u093e\u092e\u0947 \u0930\u0916\u0928\u0947 \u092a\u0921\u093c\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u092f\u0939\u0940 \u0907\u0938\u0947 \u092e\u0939\u091c\u093c \u0905\u0902\u0915\u0917\u0923\u093f\u0924 \u0915\u0940 \u092a\u0930\u0940\u0915\u094d\u0937\u093e \u0915\u0947 \u092c\u091c\u093e\u092f \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932-\u0938\u094d\u092e\u0943\u0924\u093f \u0935 \u0917\u0924\u093f \u0915\u0940 \u0915\u0938\u0930\u0924 \u092c\u0928\u093e\u0924\u093e \u0939\u0948\u0964"]],variants:"\u092c\u0926\u0932\u093e\u0935 \u0938\u0902\u0915\u094d\u0930\u093f\u092f\u093e\u0913\u0902 \u0915\u094b \u092c\u0926\u0932\u0924\u0947 \u0939\u0948\u0902 (\u0938\u093f\u0930\u094d\u092b\u093c \u091c\u094b\u0921\u093c \u0914\u0930 \u0918\u091f\u093e\u0935, \u092f\u093e \u092a\u0942\u0930\u093e \u0917\u0941\u0923\u093e-\u092d\u093e\u0917), \u0936\u094d\u0930\u0943\u0902\u0916\u0932\u093e \u0915\u0940 \u0932\u0902\u092c\u093e\u0908, \u0938\u0902\u0916\u094d\u092f\u093e\u0913\u0902 \u0915\u0940 \u092a\u0930\u093e\u0938, \u0914\u0930 \u092f\u0939 \u0915\u093f \u0918\u0921\u093c\u0940 \u0924\u092f \u0930\u0939\u0924\u0940 \u0939\u0948 \u092f\u093e \u091c\u0948\u0938\u0947-\u091c\u0948\u0938\u0947 \u0906\u092a \u092c\u0922\u093c\u0924\u0947 \u0939\u0948\u0902 \u0924\u0947\u091c\u093c \u0939\u094b\u0924\u0940 \u091c\u093e\u0924\u0940 \u0939\u0948\u0964 \u0907\u0938\u0938\u0947 \u091c\u0941\u0921\u093c\u0947 \u0905\u0928\u0941\u0936\u093e\u0938\u0928\u094b\u0902 \u092e\u0947\u0902 \u0938\u094b\u0930\u094b\u092c\u0928-\u0906\u0927\u093e\u0930\u093f\u0924 \u092e\u093e\u0928\u0938\u093f\u0915 \u0905\u092c\u0947\u0915\u0938, \u092b\u093c\u094d\u0932\u0948\u0936 \u0905\u0902\u091c\u093c\u093e\u0928 \u0914\u0930 \u0924\u0947\u091c\u093c \u092a\u0939\u093e\u0921\u093c\u0947 \u0935\u093e\u0932\u0940 \u0915\u0938\u0930\u0924\u0947\u0902 \u0936\u093e\u092e\u093f\u0932 \u0939\u0948\u0902\u0964"},zh:{about:"\u300a\u8ba1\u6570\u5668\uff1a\u6570\u5b66\u300b\u662f\u4e00\u4e2a\u9650\u65f6\u5fc3\u7b97\u7ec3\u4e60\u3002\u5c4f\u5e55\u4e0a\u4f1a\u51fa\u73b0\u4e00\u8fde\u4e32\u5feb\u901f\u7684\u8fd0\u7b97\u6216\u4e00\u9053\u5355\u9898\uff0c\u4f60\u7684\u4efb\u52a1\u662f\u5728\u8111\u4e2d\u7b97\u51fa\u7b54\u6848\u5e76\u5728\u5012\u8ba1\u65f6\u7ed3\u675f\u524d\u8f93\u5165\uff0c\u7136\u540e\u7acb\u523b\u8fdb\u5165\u4e0b\u4e00\u9898\u3002",benefit:"\u5b83\u8bad\u7ec3\u5904\u7406\u6570\u5b57\u7684\u5de5\u4f5c\u8bb0\u5fc6\u548c\u52a0\u5de5\u901f\u5ea6\u2014\u2014\u5728\u8111\u4e2d\u4fdd\u6301\u4e2d\u95f4\u7ed3\u679c\u3001\u5957\u7528\u6b63\u786e\u7684\u8fd0\u7b97\uff0c\u5e76\u5728\u65f6\u95f4\u538b\u529b\u4e0b\u5feb\u901f\u800c\u51c6\u786e\u5730\u8c03\u53d6\u57fa\u672c\u7684\u6570\u5b57\u4e8b\u5b9e\u3002",history:"\u5fc3\u7b97\u662f\u6700\u53e4\u8001\u7684\u4e60\u5f97\u6280\u80fd\u4e4b\u4e00\uff0c\u51e0\u767e\u5e74\u6765\u901a\u8fc7\u7b97\u76d8\u548c\u73e0\u7b97\u3001\u4ee5\u53ca\u65e5\u5e38\u5e02\u96c6\u4e0e\u4e70\u5356\u4e2d\u7684\u7b97\u672f\u5f97\u4ee5\u4f20\u6388\u3002\u540e\u6765\uff0c\u8bf8\u5982\u65e5\u5f0f\u5fc3\u73e0\u7b97\uff08\u53ca\u5176\u884d\u751f\u7684\u95ea\u7b97\uff09\u3001\u5420\u9640\u6570\u5b66\u548c\u7279\u62c9\u4ea8\u4f2f\u683c\u901f\u7b97\u6cd5\u7b49\u901f\u7b97\u4f53\u7cfb\uff0c\u628a\u66f4\u5feb\u8fd0\u7b97\u7684\u7a8d\u95e8\u7cfb\u7edf\u5316\u4e86\uff0c\u800c\u50cf\u8fd9\u6837\u7684\u9650\u65f6\u7b97\u672f\u7ec3\u4e60\u6b63\u662f\u8fd9\u4e00\u60a0\u4e45\u4f20\u7edf\u7684\u6570\u5b57\u540e\u88d4\u3002",creator:"\u5b83\u6ca1\u6709\u5355\u4e00\u7684\u53d1\u660e\u8005\u2014\u2014\u5fc3\u7b97\u662f\u4e00\u9879\u901a\u7528\u7ec3\u4e60\uff0c\u5f52\u5c5e\u4e8e\u7b97\u76d8\u4e0e\u5b66\u6821\u7b97\u672f\u8bad\u7ec3\u7684\u5e7f\u9614\u4f20\u7edf\u3002\u56f4\u7ed5\u5b83\u5b58\u5728\u4e00\u4e9b\u4ee5\u4eba\u540d\u547d\u540d\u7684\u4f53\u7cfb\uff1a\u7279\u62c9\u4ea8\u4f2f\u683c\u901f\u7b97\u6cd5\u7531Jakow Trachtenberg\u572820\u4e16\u7eaa\u4e2d\u53f6\u521b\u7acb\uff0c\u5420\u9640\u6570\u5b66\u5219\u7531Bharati Krishna Tirtha\u901a\u8fc71965\u5e74\u51fa\u7248\u7684\u4e00\u672c\u4e66\u52a0\u4ee5\u63a8\u5e7f\uff0c\u4f46\u5176\u80cc\u540e\u7684\u6280\u80fd\u6bd4\u5b83\u4eec\u90fd\u8981\u53e4\u8001\u3002",methods:"\u4e0d\u8981\u9010\u4f4d\u5728\u5fc3\u91cc\u9ed8\u5ff5\uff1b\u5b66\u4f1a\u62c6\u5757\u548c\u53d6\u6574\uff08\u628a48\u5f53\u621050\u51cf2\u6765\u5904\u7406\uff09\u3002\u628a\u57fa\u7840\u6a21\u5757\u8bb0\u7262\u2014\u2014\u5c0f\u7684\u4e58\u6cd5\u8868\u3001\u51d110\u548c\u51d1100\u7684\u8865\u6570\u2014\u2014\u8fd9\u6837\u8c03\u53d6\u624d\u80fd\u81ea\u52a8\u5316\u3002\u5148\u8ffd\u6c42\u4e00\u4e2a\u8212\u9002\u7684\u901f\u5ea6\uff0c\u518d\u53bb\u524a\u51cf\u5b83\uff1b\u5728\u9002\u5ea6\u65f6\u95f4\u538b\u529b\u4e0b\u4fdd\u8bc1\u51c6\u786e\u7387\uff0c\u80dc\u8fc7\u4e0d\u987e\u4e00\u5207\u5730\u778e\u731c\u3002",duration:"\u77ed\u800c\u9891\u7e41\u7684\u7ec3\u4e60\u6548\u679c\u6700\u597d\uff1a\u6bcf\u59295\u523010\u5206\u949f\uff0c\u80dc\u8fc7\u6bcf\u5468\u4e00\u6b21\u7684\u6f2b\u957f\u786c\u5237\u3002\u4e00\u65e6\u51c6\u786e\u7387\u5f00\u59cb\u4e0b\u6ed1\u5c31\u505c\u4e0b\u6765\uff0c\u56e0\u4e3a\u75b2\u52b3\u8bad\u7ec3\u51fa\u6765\u7684\u662f\u9a6c\u864e\u7684\u4e60\u60ef\uff0c\u800c\u4e0d\u662f\u719f\u7ec3\u3002",research:"\u624e\u5b9e\u7684\u53d1\u73b0\u5c31\u662f\u90a3\u4e2a\u663e\u800c\u6613\u89c1\u7684\uff1a\u7ec3\u4e60\u5fc3\u7b97\uff0c\u4f60\u5728\u5fc3\u7b97\u4e0a\u5c31\u4f1a\u53d8\u5f97\u660e\u663e\u66f4\u5feb\u3001\u66f4\u51c6\uff0c\u800c\u4e14\u5de5\u4f5c\u8bb0\u5fc6\u4e0e\u7b97\u672f\u80fd\u529b\u4e4b\u95f4\u5b58\u5728\u53ef\u9760\u7684\u76f8\u5173\u3002\u66f4\u5927\u7684\u90a3\u4e9b\u8bf4\u6cd5\u5219\u8f83\u5f31\uff1a\u80fd\u5426\u5e7f\u6cdb\u8fc1\u79fb\u5230\u4e00\u822c\u667a\u529b\u6216\u4e0d\u76f8\u5173\u7684\u65e5\u5e38\u4efb\u52a1\uff0c\u57fa\u672c\u4e0a\u672a\u5f97\u5230\u8bc1\u5b9e\uff1b\u5728\u4e25\u683c\u5bf9\u7167\u7684\u7814\u7a76\u4e2d\uff0c\u5065\u8111\u6e38\u620f\u4e00\u518d\u672a\u80fd\u5c55\u73b0\u51fa\u8fdc\u8fc1\u79fb\uff1b\u751a\u81f3\u8fde\u5fc3\u73e0\u7b97\u7684\u7814\u7a76\u5728\u5b83\u662f\u5426\u80fd\u63d0\u5347\u5de5\u4f5c\u8bb0\u5fc6\u672c\u8eab\u8fd9\u70b9\u4e0a\u90fd\u83ab\u8877\u4e00\u662f\u3002\u5bf9\u4efb\u4f55\u300e\uff0b\u667a\u5546\u300f\u7684\u627f\u8bfa\u90fd\u8981\u4fdd\u6301\u8c28\u614e\u3002",rec:"\u628a\u96be\u5ea6\u4fdd\u6301\u5728\u521a\u521a\u8d85\u51fa\u8212\u9002\u533a\u2014\u2014\u90a3\u79cd\u4f60\u5f97\u8d39\u70b9\u52b2\u3001\u51e0\u79d2\u949f\u624d\u80fd\u89e3\u51fa\u7684\u9898\u2014\u2014\u5e76\u4e14\u6bcf\u5929\u77ed\u4fc3\u5730\u7ec3\uff0c\u800c\u4e0d\u662f\u96be\u5f97\u6765\u4e00\u573a\u9a6c\u62c9\u677e\u3002",faq:[["\u8fd9\u4f1a\u8ba9\u6211\u66f4\u806a\u660e\u6216\u63d0\u9ad8\u667a\u5546\u5417\uff1f","\u73b0\u5b9e\u5730\u8bf4\uff0c\u4e0d\u4f1a\u3002\u4f60\u4f1a\u5728\u5fc3\u7b97\u4e0a\u53d8\u5f97\u660e\u663e\u66f4\u597d\u3001\u66f4\u5feb\uff0c\u4f46\u51e0\u4e4e\u6ca1\u6709\u53ef\u9760\u8bc1\u636e\u8868\u660e\u5b83\u80fd\u63d0\u5347\u4e00\u822c\u667a\u529b\u6216\u4e0d\u76f8\u5173\u7684\u6280\u80fd\uff0c\u6240\u4ee5\u6211\u4eec\u4e0d\u4f1a\u505a\u8fd9\u79cd\u627f\u8bfa\u3002"],["\u53d6\u6574\u6216\u7528\u901f\u7b97\u7a8d\u95e8\u7b97\u4f5c\u5f0a\u5417\uff1f","\u5b8c\u5168\u4e0d\u7b97\u2014\u2014\u62c6\u5757\u3001\u53d6\u6574\u4ee5\u53ca\u50cf\u51d1\u8865\u6570\u8fd9\u6837\u4e60\u5f97\u7684\u7a8d\u95e8\uff0c\u6b63\u662f\u5feb\u901f\u5fc3\u7b97\u9ad8\u624b\u7684\u505a\u6cd5\u3002\u76ee\u6807\u662f\u5feb\u901f\u5f97\u51fa\u6b63\u786e\u7b54\u6848\uff0c\u800c\u4e0d\u662f\u67d0\u4e00\u79cd\u7279\u5b9a\u65b9\u6cd5\u3002"],["\u8fd9\u548c\u7528\u7eb8\u7b14\u6216\u8ba1\u7b97\u5668\u505a\u6570\u5b66\u6709\u4ec0\u4e48\u533a\u522b\uff1f","\u7eb8\u7b14\u548c\u8ba1\u7b97\u5668\u628a\u5b58\u50a8\u8fd9\u4ef6\u4e8b\u5916\u5305\u51fa\u53bb\u4e86\uff1b\u5728\u8fd9\u91cc\u4f60\u5fc5\u987b\u628a\u6570\u5b57\u548c\u4e2d\u95f4\u7ed3\u679c\u4fdd\u6301\u5728\u8111\u4e2d\uff0c\u8fd9\u6b63\u662f\u5b83\u4e4b\u6240\u4ee5\u6210\u4e3a\u4e00\u9879\u5de5\u4f5c\u8bb0\u5fc6\u4e0e\u901f\u5ea6\u7ec3\u4e60\u3001\u800c\u4e0d\u53ea\u662f\u4e00\u9053\u7b97\u672f\u6d4b\u9a8c\u7684\u539f\u56e0\u3002"]],variants:"\u5404\u79cd\u53d8\u4f53\u4f1a\u6539\u53d8\u8fd0\u7b97\u7c7b\u578b\uff08\u53ea\u6709\u52a0\u51cf\uff0c\u6216\u5305\u542b\u5b8c\u6574\u7684\u4e58\u9664\uff09\u3001\u8fd0\u7b97\u94fe\u7684\u957f\u5ea6\u3001\u6570\u5b57\u7684\u8303\u56f4\uff0c\u4ee5\u53ca\u5012\u8ba1\u65f6\u662f\u56fa\u5b9a\u8fd8\u662f\u968f\u8fdb\u5ea6\u52a0\u5feb\u3002\u76f8\u5173\u7684\u95e8\u7c7b\u5305\u62ec\u57fa\u4e8e\u7b97\u76d8\u7684\u5fc3\u73e0\u7b97\u3001\u95ea\u7b97\u4ee5\u53ca\u5feb\u901f\u4e58\u6cd5\u8868\u7ec3\u4e60\u3002"}},cpt:{ru:{about:"CPT \u2014 \u044d\u0442\u043e \u043f\u0440\u043e\u0431\u0430 \u043d\u0430 \u0431\u0434\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c. \u041f\u043e \u043e\u0434\u043d\u043e\u0439 \u043c\u0435\u043b\u044c\u043a\u0430\u0435\u0442 \u0434\u043b\u0438\u043d\u043d\u0430\u044f \u043e\u0434\u043d\u043e\u043e\u0431\u0440\u0430\u0437\u043d\u0430\u044f \u0447\u0435\u0440\u0435\u0434\u0430 \u0431\u0443\u043a\u0432, \u0438 \u0432\u0430\u0448\u0430 \u0437\u0430\u0434\u0430\u0447\u0430 \u2014 \u0440\u0435\u0430\u0433\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u043d\u0430 \u043d\u0443\u0436\u043d\u044b\u0439 \u0441\u0438\u043c\u0432\u043e\u043b \u0438 \u0441\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0442\u044c\u0441\u044f \u043d\u0430 \u0432\u0441\u0435\u0445 \u043e\u0441\u0442\u0430\u043b\u044c\u043d\u044b\u0445: \u0447\u0430\u0449\u0435 \u0432\u0441\u0435\u0433\u043e \u0432\u044b \u043d\u0430\u0436\u0438\u043c\u0430\u0435\u0442\u0435 \u043d\u0430 \u043a\u0430\u0436\u0434\u0443\u044e \u0431\u0443\u043a\u0432\u0443, \u043a\u0440\u043e\u043c\u0435 \xabX\xbb, \u043b\u0438\u0431\u043e \u0442\u043e\u043b\u044c\u043a\u043e \u0442\u043e\u0433\u0434\u0430, \u043a\u043e\u0433\u0434\u0430 \u0437\u0430 \u0431\u0443\u043a\u0432\u043e\u0439-\u0441\u0438\u0433\u043d\u0430\u043b\u043e\u043c \u0438\u0434\u0451\u0442 \u043e\u043f\u0440\u0435\u0434\u0435\u043b\u0451\u043d\u043d\u0430\u044f \u0431\u0443\u043a\u0432\u0430-\u0446\u0435\u043b\u044c. \u0414\u0435\u043b\u043e \u0442\u0443\u0442 \u043d\u0435 \u0432 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u0438, \u0430 \u0432 \u0442\u043e\u043c, \u0447\u0442\u043e\u0431\u044b \u043e\u0441\u0442\u0430\u0432\u0430\u0442\u044c\u0441\u044f \u0432\u043a\u043b\u044e\u0447\u0451\u043d\u043d\u044b\u043c, \u043a\u043e\u0433\u0434\u0430 \u043f\u043e\u0447\u0442\u0438 \u043d\u0438\u0447\u0435\u0433\u043e \u043d\u0435 \u043f\u0440\u043e\u0438\u0441\u0445\u043e\u0434\u0438\u0442.",benefit:"\u0422\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442\u0441\u044f \u0443\u0441\u0442\u043e\u0439\u0447\u0438\u0432\u043e\u0435 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u0438 \u0442\u043e\u0440\u043c\u043e\u0436\u0435\u043d\u0438\u0435 \u0440\u0435\u0430\u043a\u0446\u0438\u0438 \u2014 \u0443\u043c\u0435\u043d\u0438\u0435 \u0434\u043e\u043b\u0433\u043e \u0441\u043b\u0435\u0434\u0438\u0442\u044c \u0437\u0430 \u0442\u0443\u0441\u043a\u043b\u044b\u043c, \u0431\u0435\u0434\u043d\u044b\u043c \u043d\u0430 \u0441\u043e\u0431\u044b\u0442\u0438\u044f \u043f\u043e\u0442\u043e\u043a\u043e\u043c \u0438 \u043d\u0435 \u0432\u044b\u043f\u0430\u0434\u0430\u0442\u044c \u0438\u0437 \u043d\u0435\u0433\u043e, \u0430 \u0442\u0430\u043a\u0436\u0435 \u0433\u0430\u0441\u0438\u0442\u044c \u0440\u0435\u0444\u043b\u0435\u043a\u0441 \u043d\u0430\u0436\u0430\u0442\u044c \u0442\u0430\u043c, \u0433\u0434\u0435 \u0436\u0430\u0442\u044c \u043d\u0435 \u043d\u0430\u0434\u043e. \u041d\u0430 \u044f\u0437\u044b\u043a\u0435 CPT \u044d\u0442\u043e \u043c\u0435\u043d\u044c\u0448\u0435 \u043f\u0440\u043e\u043f\u0443\u0449\u0435\u043d\u043d\u044b\u0445 \u0446\u0435\u043b\u0435\u0439, \u043c\u0435\u043d\u044c\u0448\u0435 \u0438\u043c\u043f\u0443\u043b\u044c\u0441\u0438\u0432\u043d\u044b\u0445 \u043d\u0430\u0436\u0430\u0442\u0438\u0439 \u043d\u0430 \xab\u043e\u0431\u043c\u0430\u043d\u043a\u0438\xbb \u0438 \u0431\u043e\u043b\u0435\u0435 \u0440\u043e\u0432\u043d\u043e\u0435 \u0432\u0440\u0435\u043c\u044f \u0440\u0435\u0430\u043a\u0446\u0438\u0438 \u043d\u0430 \u0432\u0441\u0435\u0439 \u0434\u0438\u0441\u0442\u0430\u043d\u0446\u0438\u0438.",history:"\u0412\u0441\u0451 \u043d\u0430\u0447\u0430\u043b\u043e\u0441\u044c \u043d\u0435 \u0441 \u0438\u0433\u0440\u044b, \u0430 \u0441 \u043a\u043b\u0438\u043d\u0438\u0447\u0435\u0441\u043a\u043e\u0439 \u043f\u0440\u043e\u0431\u044b. \u0412 1956 \u0433\u043e\u0434\u0443 \u0433\u0440\u0443\u043f\u043f\u0430 \u0438\u0437 \u041d\u0430\u0446\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u0438\u043d\u0441\u0442\u0438\u0442\u0443\u0442\u0430 \u043f\u0441\u0438\u0445\u0438\u0447\u0435\u0441\u043a\u043e\u0433\u043e \u0437\u0434\u043e\u0440\u043e\u0432\u044c\u044f \u0421\u0428\u0410 \u0441\u043e\u0431\u0440\u0430\u043b\u0430 \u043f\u0440\u0438\u0431\u043e\u0440, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u0432\u044b\u0441\u0432\u0435\u0447\u0438\u0432\u0430\u043b \u0431\u0443\u043a\u0432\u044b \u043d\u0430 \u0432\u0440\u0430\u0449\u0430\u044e\u0449\u0435\u043c\u0441\u044f \u0431\u0430\u0440\u0430\u0431\u0430\u043d\u0435, \u0447\u0442\u043e\u0431\u044b \u043f\u0440\u043e\u0432\u0435\u0440\u0438\u0442\u044c, \u0441\u043f\u043e\u0441\u043e\u0431\u043d\u044b \u043b\u0438 \u043f\u0430\u0446\u0438\u0435\u043d\u0442\u044b \u0441 \u043f\u043e\u0440\u0430\u0436\u0435\u043d\u0438\u0435\u043c \u043c\u043e\u0437\u0433\u0430 \u2014 \u043f\u0440\u0435\u0436\u0434\u0435 \u0432\u0441\u0435\u0433\u043e \u043f\u0440\u0438 \u043c\u0430\u043b\u043e\u0439 \u044d\u043f\u0438\u043b\u0435\u043f\u0441\u0438\u0438 \u2014 \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0442\u044c \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u0432\u043e \u0432\u0440\u0435\u043c\u0435\u043d\u0438. \u0421 1970-\u0445 \u043f\u0440\u043e\u0431\u0430 \u0441\u0442\u0430\u043b\u0430 \u043e\u0434\u043d\u0438\u043c \u0438\u0437 \u0441\u0442\u0430\u043d\u0434\u0430\u0440\u0442\u043d\u044b\u0445 \u0438\u043d\u0441\u0442\u0440\u0443\u043c\u0435\u043d\u0442\u043e\u0432 \u0438\u0437\u0443\u0447\u0435\u043d\u0438\u044f \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f, \u0430 \u043f\u043e\u0437\u0436\u0435 \u2014 \u043e\u0446\u0435\u043d\u043a\u0438 \u0421\u0414\u0412\u0413, \u0438 \u043e\u0431\u0440\u043e\u0441\u043b\u0430 \u043a\u043e\u043c\u043f\u044c\u044e\u0442\u0435\u0440\u043d\u044b\u043c\u0438 \u0432\u0435\u0440\u0441\u0438\u044f\u043c\u0438, \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u043f\u0440\u0438\u043c\u0435\u043d\u044f\u044e\u0442 \u0432 \u043a\u043b\u0438\u043d\u0438\u043a\u0430\u0445 \u043f\u043e \u0432\u0441\u0435\u043c\u0443 \u043c\u0438\u0440\u0443.",creator:"\u0423 \u043f\u0440\u043e\u0431\u044b \u0435\u0441\u0442\u044c \u044f\u0441\u043d\u043e\u0435 \u0430\u0432\u0442\u043e\u0440\u0441\u0442\u0432\u043e: \u0425\u0430\u043b\u044c\u0434\u043e\u0440 \u0420\u043e\u0437\u0432\u043e\u043b\u0434, \u0410\u043b\u043b\u0430\u043d \u041c\u0438\u0440\u0441\u043a\u0438, \u0418\u0440\u0432\u0438\u043d \u0421\u0430\u0440\u0430\u0441\u043e\u043d, \u042d\u0434\u0432\u0438\u043d \u0411\u0440\u044d\u043d\u0441\u043e\u043c \u0438 \u041b\u043b\u043e\u0439\u0434 \u0411\u0435\u043a, \u043e\u043f\u0443\u0431\u043b\u0438\u043a\u043e\u0432\u0430\u0432\u0448\u0438\u0435 \u0440\u0430\u0431\u043e\u0442\u0443 \xabA continuous performance test of brain damage\xbb \u0432 Journal of Consulting Psychology \u0432 1956 \u0433\u043e\u0434\u0443. \u041c\u043d\u043e\u0433\u043e\u0447\u0438\u0441\u043b\u0435\u043d\u043d\u044b\u0435 \u043f\u043e\u0437\u0434\u043d\u0438\u0435 \u0444\u043e\u0440\u043c\u044b (Conners CPT, T.O.V.A., AX-CPT \u0438 \u0434\u0440\u0443\u0433\u0438\u0435) \u2014 \u044d\u0442\u043e \u0432\u0430\u0440\u0438\u0430\u0446\u0438\u0438 \u0438\u0445 \u0437\u0430\u043c\u044b\u0441\u043b\u0430, \u0430 \u043d\u0435 \u043e\u0442\u0434\u0435\u043b\u044c\u043d\u044b\u0435 \u0438\u0437\u043e\u0431\u0440\u0435\u0442\u0435\u043d\u0438\u044f.",methods:"\u041e\u0442\u043d\u043e\u0441\u0438\u0442\u0435\u0441\u044c \u043a \u0441\u043a\u0443\u0447\u043d\u043e\u043c\u0443 \u043e\u0442\u0440\u0435\u0437\u043a\u0443 \u043a\u0430\u043a \u043a \u043d\u0430\u0441\u0442\u043e\u044f\u0449\u0435\u043c\u0443 \u0438\u0441\u043f\u044b\u0442\u0430\u043d\u0438\u044e: \u0442\u0440\u0443\u0434\u043d\u0430 \u043d\u0435 \u043f\u0435\u0440\u0432\u0430\u044f \u043c\u0438\u043d\u0443\u0442\u0430, \u0430 \u0441\u0435\u0440\u0435\u0434\u0438\u043d\u0430 \u0438 \u043a\u043e\u043d\u0435\u0446. \u0414\u0435\u0440\u0436\u0438\u0442\u0435 \u043e\u0434\u0438\u043d \u0440\u043e\u0432\u043d\u044b\u0439 \u0442\u0435\u043c\u043f \u043d\u0430\u0436\u0430\u0442\u0438\u0439, \u0430 \u043d\u0435 \u0433\u043e\u043d\u0438\u0442\u0435\u0441\u044c \u0437\u0430 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c\u044e, \u0432\u0435\u0434\u044c \u0431\u043e\u043b\u044c\u0448\u0438\u043d\u0441\u0442\u0432\u043e \u043e\u0448\u0438\u0431\u043e\u043a \u2014 \u044d\u0442\u043e \u0438\u043c\u043f\u0443\u043b\u044c\u0441\u0438\u0432\u043d\u044b\u0435 \u043d\u0430\u0436\u0430\u0442\u0438\u044f \u043d\u0430 \xabX\xbb, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u043d\u0430\u0434\u043e \u0431\u044b\u043b\u043e \u043f\u0440\u043e\u043f\u0443\u0441\u0442\u0438\u0442\u044c. \u0421\u043b\u0435\u0434\u0438\u0442\u0435 \u0437\u0430 \u043f\u0435\u0440\u0435\u043a\u043e\u0441\u043e\u043c: \u043f\u0440\u043e\u043f\u0443\u0441\u043a\u0430\u0435\u0442\u0435 \u0446\u0435\u043b\u0438 \u2014 \u0437\u043d\u0430\u0447\u0438\u0442, \u043e\u0442\u0432\u043b\u0435\u043a\u043b\u0438\u0441\u044c, \u0436\u043c\u0451\u0442\u0435 \u043d\u0430 \u043e\u0431\u043c\u0430\u043d\u043a\u0438 \u2014 \u0437\u043d\u0430\u0447\u0438\u0442, \u0441\u043b\u0438\u0448\u043a\u043e\u043c \u0440\u0435\u0437\u0432\u044b, \u0438 \u043f\u043e\u0434\u0442\u044f\u0433\u0438\u0432\u0430\u0439\u0442\u0435 \u0442\u0443 \u0441\u0442\u043e\u0440\u043e\u043d\u0443, \u0447\u0442\u043e \u043f\u0440\u043e\u0441\u0435\u0434\u0430\u0435\u0442.",duration:"\u041a\u043e\u0440\u043e\u0442\u043a\u0438\u0435 \u0438 \u0447\u0430\u0441\u0442\u044b\u0435 \u043f\u043e\u0434\u0445\u043e\u0434\u044b \u043b\u0443\u0447\u0448\u0435 \u043c\u0430\u0440\u0430\u0444\u043e\u043d\u043e\u0432: \u043f\u0440\u0438\u043c\u0435\u0440\u043d\u043e 8\u201315 \u043c\u0438\u043d\u0443\u0442 \u0437\u0430 \u0440\u0430\u0437, \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0440\u0430\u0437 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e \u2014 \u044d\u0442\u043e\u0433\u043e \u0445\u0432\u0430\u0442\u0438\u0442, \u0447\u0442\u043e\u0431\u044b \u043f\u043e\u0447\u0443\u0432\u0441\u0442\u0432\u043e\u0432\u0430\u0442\u044c \u0441\u043f\u0430\u0434 \u0431\u0434\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u0438 \u0438 \u043d\u0430\u0443\u0447\u0438\u0442\u044c\u0441\u044f \u0435\u0433\u043e \u043f\u0440\u043e\u0445\u043e\u0434\u0438\u0442\u044c. \u0427\u0430\u0441 \u043f\u043e\u0434\u0440\u044f\u0434 \u0432 \u043e\u0441\u043d\u043e\u0432\u043d\u043e\u043c \u0443\u0447\u0438\u0442 \u0442\u043e\u043c\u0443, \u0447\u0442\u043e \u0443\u0441\u0442\u0430\u044e\u0442 \u0432\u0441\u0435, \u2014 \u044d\u0442\u043e \u043f\u043e\u043b\u0435\u0437\u043d\u043e \u0437\u0430\u043c\u0435\u0442\u0438\u0442\u044c \u043e\u0434\u043d\u0430\u0436\u0434\u044b, \u043d\u043e \u043d\u0435 \u0441\u0442\u043e\u0438\u0442 \u0434\u043e\u043b\u0431\u0438\u0442\u044c \u043a\u0430\u0436\u0434\u044b\u0439 \u0434\u0435\u043d\u044c.",research:"\u0415\u0441\u043b\u0438 \u0447\u0435\u0441\u0442\u043d\u043e, \u0434\u043e\u043a\u0430\u0437\u0430\u043d\u043d\u043e\u0435 \u2014 \u0443\u0437\u043a\u043e\u0435. CPT \u043d\u0430\u0434\u0451\u0436\u043d\u043e \u0438\u0437\u043c\u0435\u0440\u044f\u0435\u0442 \u0443\u0441\u0442\u043e\u0439\u0447\u0438\u0432\u043e\u0435 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u0438 \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044c \u0438\u043c\u043f\u0443\u043b\u044c\u0441\u043e\u0432, \u0438 \u0441 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u043e\u0439 \u0432\u044b \u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u0435\u0441\u044c \u043b\u0443\u0447\u0448\u0435 \u0438\u043c\u0435\u043d\u043d\u043e \u0432 \u0441\u0430\u043c\u043e\u043c CPT: \u043c\u0435\u043d\u044c\u0448\u0435 \u043f\u0440\u043e\u043f\u0443\u0441\u043a\u043e\u0432 \u0438 \u043b\u043e\u0436\u043d\u044b\u0445 \u043d\u0430\u0436\u0430\u0442\u0438\u0439, \u0440\u043e\u0432\u043d\u0435\u0435 \u0432\u0440\u0435\u043c\u044f \u0440\u0435\u0430\u043a\u0446\u0438\u0438. \u041d\u043e \u044d\u0442\u043e \u0432 \u043e\u0441\u043d\u043e\u0432\u043d\u043e\u043c \u0442\u043e\u0442 \u043f\u0440\u0438\u0440\u043e\u0441\u0442 \u0432 \u043a\u043e\u043d\u043a\u0440\u0435\u0442\u043d\u043e\u0439 \u0437\u0430\u0434\u0430\u0447\u0435, \u043a\u043e\u0442\u043e\u0440\u043e\u0433\u043e \u0438 \u0441\u0442\u043e\u0438\u043b\u043e \u0436\u0434\u0430\u0442\u044c; \u0448\u0438\u0440\u043e\u043a\u0438\u0439 \xab\u043f\u0435\u0440\u0435\u043d\u043e\u0441\xbb \u043d\u0430 \u043f\u043e\u0432\u0441\u0435\u0434\u043d\u0435\u0432\u043d\u0443\u044e \u0441\u043e\u0431\u0440\u0430\u043d\u043d\u043e\u0441\u0442\u044c, \u0443\u0447\u0451\u0431\u0443, \u0440\u0430\u0431\u043e\u0442\u0443 \u0438\u043b\u0438 \u043d\u0430 \u043e\u0431\u0449\u0438\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0441\u043b\u0430\u0431 \u0438 \u0441\u043f\u043e\u0440\u0435\u043d, \u0430 \u0437\u0430\u044f\u0432\u043b\u0435\u043d\u0438\u044f \u043e \u0434\u0430\u043b\u0451\u043a\u043e\u043c \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0435 \u0443 \u0442\u0440\u0435\u043d\u0430\u0436\u0451\u0440\u043e\u0432 \u043c\u043e\u0437\u0433\u0430 \u0432 \u0446\u0435\u043b\u043e\u043c \u043f\u043b\u043e\u0445\u043e \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u044f\u0442\u0441\u044f. \u0423\u0447\u0442\u0438\u0442\u0435 \u0438 \u0442\u043e, \u0447\u0442\u043e CPT \u0441\u043e\u0437\u0434\u0430\u0432\u0430\u043b\u0438 \u043a\u0430\u043a \u043e\u0446\u0435\u043d\u043e\u0447\u043d\u044b\u0439 \u0438\u043d\u0441\u0442\u0440\u0443\u043c\u0435\u043d\u0442, \u0430 \u043d\u0435 \u043a\u0430\u043a \u043b\u0435\u0447\u0435\u043d\u0438\u0435: \u0441\u0438\u0441\u0442\u0435\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u0438\u0439 \u043e\u0431\u0437\u043e\u0440 2024 \u0433\u043e\u0434\u0430 \u0432 Pediatrics \u043f\u043e\u043a\u0430\u0437\u0430\u043b, \u0447\u0442\u043e \u0441\u0430\u043c\u0438 \u043f\u043e \u0441\u0435\u0431\u0435 CPT \u0441\u043b\u0430\u0431\u043e \u0433\u043e\u0434\u044f\u0442\u0441\u044f \u0434\u043b\u044f \u0434\u0438\u0430\u0433\u043d\u043e\u0441\u0442\u0438\u043a\u0438 \u0421\u0414\u0412\u0413, \u0442\u0430\u043a \u0447\u0442\u043e \u043a \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f\u043c \xab\u043f\u043e\u0447\u0438\u043d\u0438\u0442 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435\xbb \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u0435\u0441\u044c \u043e\u0441\u0442\u043e\u0440\u043e\u0436\u043d\u043e.",rec:"\u0418\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0439\u0442\u0435 \u043f\u0440\u043e\u0431\u0443, \u0447\u0442\u043e\u0431\u044b \u043f\u043e\u043d\u044f\u0442\u044c, \u043a\u0430\u043a \u043e\u0449\u0443\u0449\u0430\u0435\u0442\u0441\u044f \u0432\u0430\u0448 \u0441\u043e\u0431\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0439 \u0441\u043f\u0430\u0434, \u0438 \u043b\u043e\u0432\u0438\u0442\u044c \u0435\u0433\u043e \u043f\u043e\u0440\u0430\u043d\u044c\u0448\u0435, \u0430 \u043d\u0435 \u043a\u0430\u043a \u043b\u0435\u043a\u0430\u0440\u0441\u0442\u0432\u043e \u043e\u0442 \u0440\u0430\u0441\u0441\u0435\u044f\u043d\u043d\u043e\u0441\u0442\u0438 \u2014 \u0441\u0438\u043b\u044c\u043d\u0435\u0435 \u043d\u0430 \u043f\u043e\u0432\u0441\u0435\u0434\u043d\u0435\u0432\u043d\u043e\u0435 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u0432\u043b\u0438\u044f\u044e\u0442 \u0441\u043e\u043d \u0438 \u043c\u0435\u043d\u044c\u0448\u0435\u0435 \u0447\u0438\u0441\u043b\u043e \u043e\u0442\u0432\u043b\u0435\u0447\u0435\u043d\u0438\u0439.",faq:[["CPT \u2014 \u044d\u0442\u043e \u0442\u0435\u0441\u0442 \u0438\u043b\u0438 \u0442\u0440\u0435\u043d\u0430\u0436\u0451\u0440?","\u0418\u0437\u043d\u0430\u0447\u0430\u043b\u044c\u043d\u043e \u043a\u043b\u0438\u043d\u0438\u0447\u0435\u0441\u043a\u0430\u044f \u043f\u0440\u043e\u0431\u0430 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f, \u0438 \u044d\u0442\u043e \u043f\u043e-\u043f\u0440\u0435\u0436\u043d\u0435\u043c\u0443 \u0435\u0451 \u0433\u043b\u0430\u0432\u043d\u0430\u044f \u0440\u043e\u043b\u044c. \u0415\u0441\u043b\u0438 \u0443\u043f\u0440\u0430\u0436\u043d\u044f\u0442\u044c\u0441\u044f \u043a\u0430\u043a \u0432 \u0438\u0433\u0440\u0435, \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442 \u043d\u0430 \u0441\u0430\u043c\u043e\u0439 \u043f\u0440\u043e\u0431\u0435 \u043c\u043e\u0436\u043d\u043e \u043f\u043e\u0434\u0442\u044f\u043d\u0443\u0442\u044c, \u043d\u043e \u043b\u0435\u0447\u0435\u043d\u0438\u0435\u043c \u0435\u0451 \u043d\u0435 \u0437\u0430\u0434\u0443\u043c\u044b\u0432\u0430\u043b\u0438 \u2014 \u043d\u0435 \u0436\u0434\u0438\u0442\u0435, \u0447\u0442\u043e \u043e\u043d\u0430 \xab\u0432\u044b\u043b\u0435\u0447\u0438\u0442\xbb \u0440\u0430\u0441\u0441\u0435\u044f\u043d\u043d\u043e\u0441\u0442\u044c."],["\u041e\u043d\u0430 \u0441\u0442\u0430\u0432\u0438\u0442 \u0434\u0438\u0430\u0433\u043d\u043e\u0437 \u0421\u0414\u0412\u0413?","\u0421\u0430\u043c\u0430 \u043f\u043e \u0441\u0435\u0431\u0435 \u2014 \u043d\u0435\u0442. \u041f\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u0438 CPT \u043f\u043e\u043c\u043e\u0433\u0430\u044e\u0442 \u0432\u0440\u0430\u0447\u0443 \u0441\u043e\u0441\u0442\u0430\u0432\u0438\u0442\u044c \u043a\u0430\u0440\u0442\u0438\u043d\u0443 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f \u0438 \u0438\u043c\u043f\u0443\u043b\u044c\u0441\u0438\u0432\u043d\u043e\u0441\u0442\u0438, \u043d\u043e \u043e\u0431\u0437\u043e\u0440 2024 \u0433\u043e\u0434\u0430 \u043f\u043e\u043a\u0430\u0437\u0430\u043b, \u0447\u0442\u043e \u0432 \u043e\u0434\u0438\u043d\u043e\u0447\u043a\u0443 \u0438\u0445 \u0434\u0438\u0430\u0433\u043d\u043e\u0441\u0442\u0438\u0447\u0435\u0441\u043a\u0430\u044f \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u044c \u043e\u0433\u0440\u0430\u043d\u0438\u0447\u0435\u043d\u0430 \u2014 \u0434\u043b\u044f \u0434\u0438\u0430\u0433\u043d\u043e\u0437\u0430 \u043d\u0443\u0436\u043d\u0430 \u043f\u043e\u043b\u043d\u0430\u044f \u043e\u0446\u0435\u043d\u043a\u0430, \u0430 \u043d\u0435 \u043e\u0434\u043d\u0430 \u0446\u0438\u0444\u0440\u0430."],["\u041f\u043e\u0447\u0435\u043c\u0443 \u0447\u0435\u043c \u0434\u043e\u043b\u044c\u0448\u0435 \u0438\u0433\u0440\u0430\u044e, \u0442\u0435\u043c \u0445\u0443\u0436\u0435 \u0432\u044b\u0445\u043e\u0434\u0438\u0442?","\u042d\u0442\u043e \u0441\u043f\u0430\u0434 \u0431\u0434\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u0438: \u0443\u0441\u0442\u043e\u0439\u0447\u0438\u0432\u043e\u0435 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043d\u043d\u043e \u043f\u0440\u043e\u0441\u0435\u0434\u0430\u0435\u0442 \u0441\u043e \u0432\u0440\u0435\u043c\u0435\u043d\u0435\u043c \u043d\u0430 \u0442\u0443\u0441\u043a\u043b\u044b\u0445, \u0431\u0435\u0434\u043d\u044b\u0445 \u043d\u0430 \u0441\u043e\u0431\u044b\u0442\u0438\u044f \u0437\u0430\u0434\u0430\u0447\u0430\u0445. \u0418\u043c\u0435\u043d\u043d\u043e \u044d\u0442\u043e CPT \u0438 \u0441\u043e\u0437\u0434\u0430\u0432\u0430\u043b\u0438, \u0447\u0442\u043e\u0431\u044b \u043f\u043e\u043a\u0430\u0437\u0430\u0442\u044c, \u0442\u0430\u043a \u0447\u0442\u043e \u0437\u0430\u043c\u0435\u0442\u0438\u0442\u044c \u0441\u043e\u0431\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0439 \u0441\u043f\u0430\u0434 \u2014 \u0447\u0430\u0441\u0442\u044c \u0441\u043c\u044b\u0441\u043b\u0430."]],variants:"\u041a\u043b\u0430\u0441\u0441\u0438\u0447\u0435\u0441\u043a\u0438\u0439 X-CPT (\u0440\u0435\u0430\u0433\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u043d\u0430 \u0432\u0441\u0451, \u043a\u0440\u043e\u043c\u0435 \xabX\xbb) \u0438 AX-CPT (\u0440\u0435\u0430\u0433\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u0442\u043e\u043b\u044c\u043a\u043e \u043a\u043e\u0433\u0434\u0430 \u0437\u0430 \xabA\xbb \u0438\u0434\u0451\u0442 \xabX\xbb) \u2014 \u043e\u0441\u043d\u043e\u0432\u043d\u044b\u0435 \u0444\u043e\u0440\u043c\u044b; \u0432 \u0432\u0435\u0440\u0441\u0438\u0438 Identical Pairs \u043d\u0443\u0436\u043d\u043e \u043d\u0430\u0436\u0438\u043c\u0430\u0442\u044c, \u043a\u043e\u0433\u0434\u0430 \u0434\u0432\u0430 \u0441\u0442\u0438\u043c\u0443\u043b\u0430 \u043f\u043e\u0434\u0440\u044f\u0434 \u0441\u043e\u0432\u043f\u0430\u043b\u0438. \u041a\u0440\u043e\u043c\u0435 \u043d\u0438\u0445, \u043a\u043b\u0438\u043d\u0438\u0447\u0435\u0441\u043a\u0438\u0435 \u043d\u0430\u0431\u043e\u0440\u044b \u0434\u043e\u0431\u0430\u0432\u043b\u044f\u044e\u0442 \u0441\u043b\u0443\u0445\u043e\u0432\u044b\u0435 \u043f\u043e\u0442\u043e\u043a\u0438, \u0441\u043c\u0435\u0448\u0430\u043d\u043d\u044b\u0435 \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u043e-\u0437\u0432\u0443\u043a\u043e\u0432\u044b\u0435 \u0432\u0435\u0440\u0441\u0438\u0438, \u0431\u043b\u043e\u043a\u0438 \u0441 \u0440\u0435\u0434\u043a\u043e\u0439 \u0446\u0435\u043b\u044c\u044e (\u0432\u044b\u044f\u0432\u043b\u044f\u044e\u0442 \u043d\u0435\u0432\u043d\u0438\u043c\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c) \u0438 \u0431\u043b\u043e\u043a\u0438 \u0441 \u0447\u0430\u0441\u0442\u043e\u0439 \u0446\u0435\u043b\u044c\u044e (\u043f\u0440\u043e\u0432\u043e\u0446\u0438\u0440\u0443\u044e\u0442 \u0438\u043c\u043f\u0443\u043b\u044c\u0441\u0438\u0432\u043d\u044b\u0435 \u043e\u0448\u0438\u0431\u043a\u0438)."},en:{about:"CPT is a vigilance task. A long, monotonous stream of letters flashes by one at a time, and your job is to react to the target while holding back on everything else \u2014 most often you tap for every letter except 'X', or you tap only when a 'cue' letter is followed by a specific 'probe'. The point is not speed but staying switched on when almost nothing is happening.",benefit:"It trains sustained attention and response inhibition \u2014 your ability to keep monitoring a dull, low-event stream without zoning out, and to suppress the reflex to press when you should not. In CPT terms, that means fewer missed targets (omissions), fewer impulsive taps on foils (commissions), and steadier reaction times over the long haul.",history:"It began as a clinical test, not a game. In 1956 a team at the US National Institute of Mental Health built a device that flashed letters on a rotating drum to measure whether patients with brain damage \u2014 especially petit mal epilepsy \u2014 could keep attending over time. From the 1970s onward it became one of the standard tools for studying attention and, later, for assessing ADHD, spawning computerised versions used in clinics worldwide.",creator:"There is a clear origin: Haldor Rosvold, Allan Mirsky, Irwin Sarason, Edwin Bransome and Lloyd Beck, who published 'A continuous performance test of brain damage' in the Journal of Consulting Psychology in 1956. The many later forms (Conners CPT, T.O.V.A., AX-CPT and others) are variations on their idea, not separate inventions.",methods:"Treat the boring stretch as the real test: the hard part is the middle and the end, not the start. Settle on one steady tempo of responding rather than racing, since most errors are impulsive taps on the 'X' you should have withheld. Watch the trade-off \u2014 if you are missing targets you have drifted off, if you are tapping foils you are too trigger-happy \u2014 and nudge whichever side is failing.",duration:"Short and frequent beats marathon sessions: roughly 8 to 15 minutes at a time, a few times a week, is plenty to feel the vigilance dip and learn to ride through it. Sitting for an hour mainly teaches you that everyone fades \u2014 useful to notice once, not worth grinding daily.",research:"The honest evidence is narrow. CPT reliably measures sustained attention and impulse control, and with practice you get better at the CPT itself \u2014 fewer omissions and commissions, more stable reaction time. But that is largely the task-specific gain you would expect; broad 'transfer' to everyday focus, school or work performance, or general intelligence is weak and contested, and far-transfer claims from brain training in general have a poor replication record. Note too that CPT was built as an assessment, not a treatment \u2014 a 2024 systematic review in Pediatrics found CPTs have limited accuracy for diagnosing ADHD on their own, so treat any 'fixes your attention' promise with caution.",rec:"Use it to learn what your own fade feels like and to catch it early, not as a cure for distraction \u2014 pair it with sleep and fewer interruptions, which move everyday attention far more.",faq:[["Is CPT a test or a training exercise?","Originally a clinical test of attention, and that is still its main role. Practising it like a game can sharpen your performance on the task, but it was never designed as a treatment, so do not expect it to 'cure' distraction."],["Does it diagnose ADHD?","Not on its own. CPT scores can support a clinician's picture of attention and impulsivity, but a 2024 systematic review found their standalone diagnostic accuracy is limited \u2014 diagnosis needs a full assessment, not a single score."],["Why do I get worse the longer I play?","That is the vigilance decrement \u2014 sustained attention naturally sags over time on dull, low-event tasks. It is the very thing CPT was built to expose, so noticing your own fade is part of the point."]],variants:"The classic X-CPT (respond to all but 'X') and AX-CPT (respond only when 'A' is followed by 'X') are the core forms; the Identical Pairs version asks you to react when two stimuli in a row match. Beyond these, clinical kits add auditory streams, mixed visual-and-sound versions, infrequent-target blocks that pull for inattention, and frequent-target blocks that pull for impulsive errors."},es:{about:"El CPT es una tarea de vigilancia. Un flujo largo y mon\xf3tono de letras pasa una a una, y tu trabajo es reaccionar al objetivo conteni\xe9ndote ante todo lo dem\xe1s: lo m\xe1s habitual es que pulses ante cada letra salvo la 'X', o que pulses solo cuando una letra 'se\xf1al' va seguida de una 'sonda' concreta. Lo importante no es la velocidad, sino seguir alerta cuando casi no pasa nada.",benefit:"Entrena la atenci\xf3n sostenida y la inhibici\xf3n de respuesta: tu capacidad de seguir vigilando un flujo aburrido y con pocos eventos sin desconectarte, y de frenar el reflejo de pulsar cuando no deber\xedas. En t\xe9rminos del CPT, eso significa menos objetivos perdidos (omisiones), menos pulsaciones impulsivas ante los se\xf1uelos (comisiones) y tiempos de reacci\xf3n m\xe1s estables a la larga.",history:"Naci\xf3 como prueba cl\xednica, no como juego. En 1956 un equipo del Instituto Nacional de Salud Mental de EE. UU. construy\xf3 un aparato que mostraba letras en un tambor giratorio para medir si los pacientes con da\xf1o cerebral \u2014en especial epilepsia de peque\xf1o mal\u2014 pod\xedan mantener la atenci\xf3n a lo largo del tiempo. A partir de los a\xf1os setenta se convirti\xf3 en una de las herramientas est\xe1ndar para estudiar la atenci\xf3n y, m\xe1s tarde, para evaluar el TDAH, dando lugar a versiones informatizadas usadas en cl\xednicas de todo el mundo.",creator:"Tiene un origen claro: Haldor Rosvold, Allan Mirsky, Irwin Sarason, Edwin Bransome y Lloyd Beck, que publicaron 'A continuous performance test of brain damage' en el Journal of Consulting Psychology en 1956. Las numerosas formas posteriores (Conners CPT, T.O.V.A., AX-CPT y otras) son variaciones de su idea, no invenciones aparte.",methods:"Trata el tramo aburrido como la verdadera prueba: lo dif\xedcil es el medio y el final, no el arranque. Fija un \xfanico tempo de respuesta estable en lugar de acelerar, ya que la mayor\xeda de los errores son pulsaciones impulsivas ante la 'X' que deber\xedas haber retenido. Vigila el equilibrio: si pierdes objetivos es que te has despistado, si pulsas ante los se\xf1uelos es que vas demasiado disparado, y corrige el lado que est\xe9 fallando.",duration:"Corto y frecuente gana a las sesiones marat\xf3n: unos 8 a 15 minutos cada vez, algunas veces por semana, bastan para notar la ca\xedda de la vigilancia y aprender a sobrellevarla. Sentarte una hora te ense\xf1a sobre todo que todo el mundo se desinfla, algo \xfatil de notar una vez, pero que no merece la pena machacar a diario.",research:"La evidencia honesta es estrecha. El CPT mide de forma fiable la atenci\xf3n sostenida y el control de los impulsos, y con la pr\xe1ctica mejoras en el propio CPT: menos omisiones y comisiones, un tiempo de reacci\xf3n m\xe1s estable. Pero eso es en gran medida la mejora espec\xedfica de la tarea que cabr\xeda esperar; la 'transferencia' amplia a la concentraci\xf3n cotidiana, al rendimiento en los estudios o el trabajo, o a la inteligencia general es d\xe9bil y discutida, y las afirmaciones de transferencia lejana del entrenamiento cerebral en general tienen un mal historial de replicaci\xf3n. Ten en cuenta adem\xe1s que el CPT se construy\xf3 como evaluaci\xf3n, no como tratamiento: una revisi\xf3n sistem\xe1tica de 2024 en Pediatrics hall\xf3 que los CPT tienen una exactitud limitada para diagnosticar el TDAH por s\xed solos, as\xed que toma con cautela cualquier promesa de que 'arregla tu atenci\xf3n'.",rec:"\xdasalo para aprender c\xf3mo se siente tu propia ca\xedda de atenci\xf3n y para detectarla pronto, no como cura para la distracci\xf3n; comb\xednalo con dormir bien y menos interrupciones, que mueven mucho m\xe1s la atenci\xf3n cotidiana.",faq:[["\xbfEl CPT es una prueba o un ejercicio de entrenamiento?","En origen es una prueba cl\xednica de atenci\xf3n, y ese sigue siendo su papel principal. Practicarlo como un juego puede afinar tu rendimiento en la tarea, pero nunca se dise\xf1\xf3 como tratamiento, as\xed que no esperes que 'cure' la distracci\xf3n."],["\xbfDiagnostica el TDAH?","No por s\xed solo. Las puntuaciones del CPT pueden respaldar la visi\xf3n que tiene el cl\xednico de la atenci\xf3n y la impulsividad, pero una revisi\xf3n sistem\xe1tica de 2024 hall\xf3 que su exactitud diagn\xf3stica aislada es limitada: el diagn\xf3stico requiere una evaluaci\xf3n completa, no una sola puntuaci\xf3n."],["\xbfPor qu\xe9 empeoro cuanto m\xe1s juego?","Es el decremento de la vigilancia: la atenci\xf3n sostenida decae de forma natural con el tiempo en tareas aburridas y de pocos eventos. Es justo lo que el CPT se construy\xf3 para sacar a la luz, as\xed que notar tu propia ca\xedda forma parte del objetivo."]],variants:"El cl\xe1sico X-CPT (responder a todo salvo a la 'X') y el AX-CPT (responder solo cuando la 'A' va seguida de la 'X') son las formas centrales; la versi\xf3n de Pares Id\xe9nticos te pide reaccionar cuando dos est\xedmulos seguidos coinciden. M\xe1s all\xe1 de estas, los kits cl\xednicos a\xf1aden flujos auditivos, versiones mixtas visuales y sonoras, bloques con objetivos poco frecuentes que tiran hacia la desatenci\xf3n y bloques con objetivos frecuentes que tiran hacia los errores impulsivos."},de:{about:"Der CPT ist eine Vigilanzaufgabe. Ein langer, eint\xf6niger Strom von Buchstaben zieht einzeln vorbei, und deine Aufgabe ist es, auf das Ziel zu reagieren und alles andere zur\xfcckzuhalten \u2013 am h\xe4ufigsten tippst du bei jedem Buchstaben au\xdfer dem \u201eX\u201c, oder du tippst nur, wenn auf einen \u201eHinweis\u201c-Buchstaben ein bestimmter \u201ePr\xfcf\u201c-Buchstabe folgt. Es geht nicht um Geschwindigkeit, sondern darum, eingeschaltet zu bleiben, wenn fast nichts passiert.",benefit:"Trainiert werden die Daueraufmerksamkeit und die Reaktionshemmung \u2013 deine F\xe4higkeit, einen faden, ereignisarmen Strom weiter zu \xfcberwachen, ohne wegzudriften, und den Reflex zu dr\xfccken zu unterdr\xfccken, wenn du es nicht solltest. In CPT-Begriffen hei\xdft das: weniger verpasste Ziele (Auslassungen), weniger impulsive Treffer auf Ablenker (Fehlreaktionen) und gleichm\xe4\xdfigere Reaktionszeiten \xfcber die lange Strecke.",history:"Er begann als klinischer Test, nicht als Spiel. 1956 baute ein Team am US-amerikanischen National Institute of Mental Health ein Ger\xe4t, das Buchstaben auf einer rotierenden Trommel aufblitzen lie\xdf, um zu messen, ob Patienten mit Hirnsch\xe4den \u2013 besonders bei Absence-Epilepsie \u2013 \xfcber die Zeit aufmerksam bleiben konnten. Ab den 1970er-Jahren wurde er zu einem der Standardwerkzeuge der Aufmerksamkeitsforschung und sp\xe4ter zur Erfassung von ADHS und brachte computergest\xfctzte Versionen hervor, die weltweit in Kliniken genutzt werden.",creator:"Es gibt einen klaren Ursprung: Haldor Rosvold, Allan Mirsky, Irwin Sarason, Edwin Bransome und Lloyd Beck, die 1956 \u201eA continuous performance test of brain damage\u201c im Journal of Consulting Psychology ver\xf6ffentlichten. Die vielen sp\xe4teren Formen (Conners CPT, T.O.V.A., AX-CPT und andere) sind Variationen ihrer Idee, keine eigenst\xe4ndigen Erfindungen.",methods:"Behandle die langweilige Strecke als den eigentlichen Test: Der schwere Teil ist die Mitte und das Ende, nicht der Anfang. Lege dich auf ein gleichm\xe4\xdfiges Antworttempo fest, statt zu rasen, denn die meisten Fehler sind impulsive Treffer auf das \u201eX\u201c, das du h\xe4ttest zur\xfcckhalten sollen. Achte auf das Wechselspiel \u2013 wenn du Ziele verpasst, bist du abgedriftet, wenn du Ablenker triffst, bist du zu vorschnell \u2013 und steuere jeweils die Seite nach, die gerade versagt.",duration:"Kurz und h\xe4ufig schl\xe4gt Marathon-Sitzungen: Etwa 8 bis 15 Minuten am St\xfcck, ein paar Mal pro Woche, reichen, um den Vigilanzeinbruch zu sp\xfcren und zu lernen, ihn durchzustehen. Eine Stunde zu sitzen lehrt dich vor allem, dass jeder nachl\xe4sst \u2013 einmal n\xfctzlich zu bemerken, aber nicht wert, t\xe4glich daran zu schinden.",research:"Die ehrliche Beleglage ist eng. Der CPT misst zuverl\xe4ssig Daueraufmerksamkeit und Impulskontrolle, und mit \xdcbung wirst du besser im CPT selbst \u2013 weniger Auslassungen und Fehlreaktionen, stabilere Reaktionszeit. Aber das ist weitgehend der aufgabenspezifische Gewinn, den man erwarten w\xfcrde; ein breiter \u201eTransfer\u201c auf die allt\xe4gliche Konzentration, auf Schul- oder Arbeitsleistung oder auf die allgemeine Intelligenz ist schwach und umstritten, und Behauptungen \xfcber Fern-Transfer durch Gehirntraining haben generell eine schlechte Replikationsbilanz. Beachte zudem, dass der CPT als Diagnostik gebaut wurde, nicht als Behandlung \u2013 eine systematische \xdcbersichtsarbeit von 2024 in Pediatrics fand, dass CPTs f\xfcr sich allein eine begrenzte Genauigkeit f\xfcr die ADHS-Diagnose haben, begegne also jedem Versprechen \u201erepariert deine Aufmerksamkeit\u201c mit Vorsicht.",rec:"Nutze ihn, um zu lernen, wie sich dein eigenes Nachlassen anf\xfchlt, und um es fr\xfch abzufangen, nicht als Heilmittel gegen Ablenkung \u2013 kombiniere ihn mit Schlaf und weniger Unterbrechungen, die die allt\xe4gliche Aufmerksamkeit weit st\xe4rker bewegen.",faq:[["Ist der CPT ein Test oder eine Trainings\xfcbung?","Urspr\xfcnglich ein klinischer Aufmerksamkeitstest, und das ist nach wie vor seine Hauptrolle. Ihn wie ein Spiel zu \xfcben kann deine Leistung in der Aufgabe sch\xe4rfen, aber er war nie als Behandlung gedacht \u2013 erwarte also nicht, dass er Ablenkung \u201eheilt\u201c."],["Diagnostiziert er ADHS?","Nicht allein. CPT-Werte k\xf6nnen das Bild einer Fachperson von Aufmerksamkeit und Impulsivit\xe4t st\xfctzen, aber eine systematische \xdcbersichtsarbeit von 2024 fand, dass ihre alleinige diagnostische Genauigkeit begrenzt ist \u2013 eine Diagnose braucht eine vollst\xe4ndige Abkl\xe4rung, nicht einen einzelnen Wert."],["Warum werde ich schlechter, je l\xe4nger ich spiele?","Das ist das Vigilanzdefizit \u2013 die Daueraufmerksamkeit sackt bei faden, ereignisarmen Aufgaben mit der Zeit nat\xfcrlicherweise ab. Genau das sollte der CPT sichtbar machen, daher geh\xf6rt es zum Sinn der Sache, das eigene Nachlassen zu bemerken."]],variants:"Der klassische X-CPT (reagiere auf alles au\xdfer \u201eX\u201c) und der AX-CPT (reagiere nur, wenn auf \u201eA\u201c ein \u201eX\u201c folgt) sind die Grundformen; die Identical-Pairs-Version verlangt, dass du reagierst, wenn zwei Reize in Folge \xfcbereinstimmen. Dar\xfcber hinaus erg\xe4nzen klinische Sets auditive Str\xf6me, gemischte Seh-und-H\xf6r-Versionen, Bl\xf6cke mit seltenem Ziel, die zur Unaufmerksamkeit verleiten, und Bl\xf6cke mit h\xe4ufigem Ziel, die zu impulsiven Fehlern verleiten."},pt:{about:"O CPT \xe9 uma tarefa de vigil\xe2ncia. Um fluxo longo e mon\xf3tono de letras passa uma de cada vez, e a sua fun\xe7\xe3o \xe9 reagir ao alvo enquanto se cont\xe9m diante de tudo o resto \u2014 na forma mais comum, voc\xea toca para todas as letras exceto o 'X', ou toca apenas quando uma letra de 'pista' \xe9 seguida por uma 'sonda' espec\xedfica. O objetivo n\xe3o \xe9 a velocidade, mas manter-se ligado quando quase nada acontece.",benefit:"Treina a aten\xe7\xe3o sustentada e a inibi\xe7\xe3o da resposta \u2014 a sua capacidade de continuar a monitorizar um fluxo enfadonho e de poucos eventos sem desligar, e de suprimir o reflexo de pressionar quando n\xe3o deveria. Em termos de CPT, isso significa menos alvos perdidos (omiss\xf5es), menos toques impulsivos nos distratores (comiss\xf5es) e tempos de rea\xe7\xe3o mais est\xe1veis ao longo do percurso.",history:"Come\xe7ou como teste cl\xednico, n\xe3o como jogo. Em 1956, uma equipe do National Institute of Mental Health dos EUA construiu um aparelho que projetava letras num tambor girat\xf3rio para medir se pacientes com les\xe3o cerebral \u2014 em especial epilepsia de pequeno mal \u2014 conseguiam manter a aten\xe7\xe3o ao longo do tempo. A partir dos anos 1970 tornou-se uma das ferramentas padr\xe3o para estudar a aten\xe7\xe3o e, mais tarde, para avaliar o TDAH, dando origem a vers\xf5es computorizadas usadas em cl\xednicas pelo mundo todo.",creator:"H\xe1 uma origem clara: Haldor Rosvold, Allan Mirsky, Irwin Sarason, Edwin Bransome e Lloyd Beck, que publicaram 'A continuous performance test of brain damage' no Journal of Consulting Psychology em 1956. As muitas formas posteriores (Conners CPT, T.O.V.A., AX-CPT e outras) s\xe3o varia\xe7\xf5es da ideia deles, n\xe3o inven\xe7\xf5es \xe0 parte.",methods:"Trate o trecho mon\xf3tono como o verdadeiro teste: a parte dif\xedcil \xe9 o meio e o fim, n\xe3o o come\xe7o. Adote um \xfanico ritmo constante de resposta em vez de acelerar, j\xe1 que a maioria dos erros s\xe3o toques impulsivos no 'X' que voc\xea deveria ter contido. Observe o equil\xedbrio \u2014 se est\xe1 perdendo alvos, voc\xea se desligou; se est\xe1 tocando nos distratores, est\xe1 com o gatilho f\xe1cil demais \u2014 e ajuste o lado que estiver falhando.",duration:"Curto e frequente vence sess\xf5es maratonianas: cerca de 8 a 15 minutos de cada vez, algumas vezes por semana, basta para sentir a queda de vigil\xe2ncia e aprender a atravess\xe1-la. Ficar uma hora ensina, sobretudo, que todos perdem o f\xf4lego \u2014 \xfatil de notar uma vez, mas n\xe3o vale a pena repetir todos os dias.",research:"A evid\xeancia honesta \xe9 estreita. O CPT mede de forma fi\xe1vel a aten\xe7\xe3o sustentada e o controle de impulsos, e com a pr\xe1tica voc\xea melhora no pr\xf3prio CPT \u2014 menos omiss\xf5es e comiss\xf5es, tempo de rea\xe7\xe3o mais est\xe1vel. Mas isso \xe9, em grande parte, o ganho espec\xedfico da tarefa que seria de esperar; a 'transfer\xeancia' ampla para o foco no dia a dia, o desempenho escolar ou no trabalho, ou a intelig\xeancia geral, \xe9 fraca e contestada, e as alega\xe7\xf5es de transfer\xeancia distante a partir do treino cerebral em geral t\xeam um hist\xf3rico fraco de replica\xe7\xe3o. Note ainda que o CPT foi constru\xeddo como avalia\xe7\xe3o, n\xe3o como tratamento \u2014 uma revis\xe3o sistem\xe1tica de 2024 na Pediatrics concluiu que os CPTs t\xeam exatid\xe3o limitada para diagnosticar TDAH por si s\xf3s, ent\xe3o encare com cautela qualquer promessa de que ele 'conserta a sua aten\xe7\xe3o'.",rec:"Use-o para aprender como \xe9 a sua pr\xf3pria queda de aten\xe7\xe3o e para detect\xe1-la cedo, n\xe3o como cura para a distra\xe7\xe3o \u2014 combine-o com sono e menos interrup\xe7\xf5es, que mexem muito mais com a aten\xe7\xe3o di\xe1ria.",faq:[["O CPT \xe9 um teste ou um exerc\xedcio de treino?","Originalmente um teste cl\xednico de aten\xe7\xe3o, e esse continua a ser o seu papel principal. Pratic\xe1-lo como um jogo pode afinar o seu desempenho na tarefa, mas ele nunca foi concebido como tratamento, ent\xe3o n\xe3o espere que 'cure' a distra\xe7\xe3o."],["Ele diagnostica TDAH?","N\xe3o por si s\xf3. As pontua\xe7\xf5es do CPT podem apoiar o quadro que o cl\xednico faz da aten\xe7\xe3o e da impulsividade, mas uma revis\xe3o sistem\xe1tica de 2024 concluiu que a sua exatid\xe3o diagn\xf3stica isolada \xe9 limitada \u2014 o diagn\xf3stico exige uma avalia\xe7\xe3o completa, n\xe3o uma \xfanica pontua\xe7\xe3o."],["Por que eu pioro quanto mais tempo jogo?","\xc9 o decremento de vigil\xe2ncia \u2014 a aten\xe7\xe3o sustentada naturalmente cede com o tempo em tarefas enfadonhas e de poucos eventos. \xc9 justamente aquilo que o CPT foi constru\xeddo para expor, ent\xe3o notar a sua pr\xf3pria queda faz parte do objetivo."]],variants:"O cl\xe1ssico X-CPT (responder a tudo menos ao 'X') e o AX-CPT (responder apenas quando o 'A' \xe9 seguido por 'X') s\xe3o as formas centrais; a vers\xe3o de Pares Id\xeanticos pede que voc\xea reaja quando dois est\xedmulos seguidos coincidem. Al\xe9m desses, os kits cl\xednicos acrescentam fluxos auditivos, vers\xf5es mistas de vis\xe3o e som, blocos de alvos raros que puxam para a desaten\xe7\xe3o e blocos de alvos frequentes que puxam para os erros impulsivos."},hi:{about:"CPT \u090f\u0915 \u0938\u0924\u0930\u094d\u0915\u0924\u093e (vigilance) \u0915\u093e\u0930\u094d\u092f \u0939\u0948\u0964 \u0905\u0915\u094d\u0937\u0930\u094b\u0902 \u0915\u0940 \u090f\u0915 \u0932\u0902\u092c\u0940, \u090a\u092c\u093e\u090a \u0927\u093e\u0930\u093e \u090f\u0915-\u090f\u0915 \u0915\u0930\u0915\u0947 \u091a\u092e\u0915\u0924\u0940 \u0939\u0941\u0908 \u0917\u0941\u091c\u093c\u0930\u0924\u0940 \u0939\u0948, \u0914\u0930 \u0906\u092a\u0915\u093e \u0915\u093e\u092e \u0939\u0948 \u0932\u0915\u094d\u0937\u094d\u092f \u092a\u0930 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0926\u0947\u0928\u093e \u092a\u0930 \u092c\u093e\u0915\u093c\u0940 \u0938\u092c \u092a\u0930 \u0939\u093e\u0925 \u0930\u094b\u0915\u0947 \u0930\u0916\u0928\u093e \u2014 \u0905\u0915\u0938\u0930 \u0906\u092a 'X' \u0915\u094b \u091b\u094b\u0921\u093c\u0915\u0930 \u0939\u0930 \u0905\u0915\u094d\u0937\u0930 \u092a\u0930 \u091f\u0948\u092a \u0915\u0930\u0924\u0947 \u0939\u0948\u0902, \u092f\u093e \u0938\u093f\u0930\u094d\u092b\u093c \u0924\u092d\u0940 \u091f\u0948\u092a \u0915\u0930\u0924\u0947 \u0939\u0948\u0902 \u091c\u092c \u0915\u093f\u0938\u0940 '\u0938\u0902\u0915\u0947\u0924' \u0905\u0915\u094d\u0937\u0930 \u0915\u0947 \u092c\u093e\u0926 \u0915\u094b\u0908 \u0916\u093e\u0938 '\u091c\u093e\u0901\u091a' \u0905\u0915\u094d\u0937\u0930 \u0906\u090f\u0964 \u092c\u093e\u0924 \u0917\u0924\u093f \u0915\u0940 \u0928\u0939\u0940\u0902 \u0939\u0948, \u092c\u0932\u094d\u0915\u093f \u0924\u092c \u091a\u094c\u0915\u0938 \u092c\u0928\u0947 \u0930\u0939\u0928\u0947 \u0915\u0940 \u0939\u0948 \u091c\u092c \u0932\u0917\u092d\u0917 \u0915\u0941\u091b \u0939\u094b \u0939\u0940 \u0928\u0939\u0940\u0902 \u0930\u0939\u093e\u0964",benefit:"\u092f\u0939 \u0928\u093f\u0930\u0902\u0924\u0930 \u0927\u094d\u092f\u093e\u0928 \u0914\u0930 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0928\u093f\u0930\u094b\u0927 \u0915\u094b \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u093f\u0924 \u0915\u0930\u0924\u093e \u0939\u0948 \u2014 \u092f\u093e\u0928\u0940 \u090f\u0915 \u0928\u0940\u0930\u0938, \u0915\u092e-\u0918\u091f\u0928\u093e \u0935\u093e\u0932\u0940 \u0927\u093e\u0930\u093e \u092a\u0930 \u092c\u093f\u0928\u093e \u0916\u094b \u091c\u093e\u090f \u0928\u091c\u093c\u0930 \u0930\u0916\u0924\u0947 \u0930\u0939\u0928\u0947 \u0915\u0940 \u0914\u0930 \u091c\u092c \u0926\u092c\u093e\u0928\u093e \u0928\u0939\u0940\u0902 \u091a\u093e\u0939\u093f\u090f \u0924\u092c \u0926\u092c\u093e\u0928\u0947 \u0915\u0940 \u092a\u094d\u0930\u0924\u093f\u0935\u0930\u094d\u0924\u0940 \u0907\u091a\u094d\u091b\u093e \u0915\u094b \u0930\u094b\u0915\u0928\u0947 \u0915\u0940 \u0906\u092a\u0915\u0940 \u0915\u094d\u0937\u092e\u0924\u093e\u0964 CPT \u0915\u0940 \u092d\u093e\u0937\u093e \u092e\u0947\u0902 \u0907\u0938\u0915\u093e \u092e\u0924\u0932\u092c \u0939\u0948 \u0915\u092e \u091b\u0942\u091f\u0947 \u0939\u0941\u090f \u0932\u0915\u094d\u0937\u094d\u092f (omissions), \u091b\u0932\u093e\u0935\u094b\u0902 \u092a\u0930 \u0915\u092e \u0906\u0935\u0947\u0917\u0940 \u091f\u0948\u092a (commissions), \u0914\u0930 \u0932\u0902\u092c\u0947 \u0938\u092e\u092f \u0924\u0915 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0938\u094d\u0925\u093f\u0930 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0917\u0924\u093f\u0964",history:"\u0907\u0938\u0915\u0940 \u0936\u0941\u0930\u0941\u0906\u0924 \u090f\u0915 \u0916\u0947\u0932 \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u0928\u0939\u0940\u0902, \u092c\u0932\u094d\u0915\u093f \u090f\u0915 \u0915\u094d\u0932\u093f\u0928\u093f\u0915\u0932 \u092a\u0930\u0940\u0915\u094d\u0937\u0923 \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u0939\u0941\u0908\u0964 1956 \u092e\u0947\u0902 \u0905\u092e\u0947\u0930\u093f\u0915\u0940 National Institute of Mental Health \u0915\u0940 \u090f\u0915 \u091f\u0940\u092e \u0928\u0947 \u090f\u0915 \u0909\u092a\u0915\u0930\u0923 \u092c\u0928\u093e\u092f\u093e \u091c\u094b \u090f\u0915 \u0918\u0942\u092e\u0924\u0947 \u0922\u094b\u0932 \u092a\u0930 \u0905\u0915\u094d\u0937\u0930 \u091a\u092e\u0915\u093e\u0924\u093e \u0925\u093e, \u092f\u0939 \u0928\u093e\u092a\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0915\u093f \u0915\u094d\u092f\u093e \u092e\u0938\u094d\u0924\u093f\u0937\u094d\u0915-\u0915\u094d\u0937\u0924\u093f \u0935\u093e\u0932\u0947 \u092e\u0930\u0940\u091c\u093c \u2014 \u0916\u093e\u0938\u0915\u0930 petit mal \u092e\u093f\u0930\u094d\u0917\u0940 \u0935\u093e\u0932\u0947 \u2014 \u0938\u092e\u092f \u0915\u0947 \u0938\u093e\u0925 \u0927\u094d\u092f\u093e\u0928 \u092c\u0928\u093e\u090f \u0930\u0916 \u092a\u093e\u0924\u0947 \u0939\u0948\u0902\u0964 1970 \u0915\u0947 \u0926\u0936\u0915 \u0938\u0947 \u0906\u0917\u0947 \u092f\u0939 \u0927\u094d\u092f\u093e\u0928 \u0915\u0947 \u0905\u0927\u094d\u092f\u092f\u0928 \u0915\u0947 \u092e\u093e\u0928\u0915 \u0914\u091c\u093c\u093e\u0930\u094b\u0902 \u092e\u0947\u0902 \u0938\u0947 \u090f\u0915 \u092c\u0928 \u0917\u092f\u093e \u0914\u0930 \u092c\u093e\u0926 \u092e\u0947\u0902 ADHD \u092a\u0930\u0916\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f, \u0914\u0930 \u0926\u0941\u0928\u093f\u092f\u093e \u092d\u0930 \u0915\u0947 \u0915\u094d\u0932\u093f\u0928\u093f\u0915\u094b\u0902 \u092e\u0947\u0902 \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0939\u094b\u0928\u0947 \u0935\u093e\u0932\u0947 \u0915\u092e\u094d\u092a\u094d\u092f\u0942\u091f\u0930\u0940\u0915\u0943\u0924 \u0938\u0902\u0938\u094d\u0915\u0930\u0923\u094b\u0902 \u0915\u094b \u091c\u0928\u094d\u092e \u0926\u093f\u092f\u093e\u0964",creator:"\u0907\u0938\u0915\u093e \u0938\u094d\u092a\u0937\u094d\u091f \u0938\u094d\u0930\u094b\u0924 \u0939\u0948: Haldor Rosvold, Allan Mirsky, Irwin Sarason, Edwin Bransome \u0914\u0930 Lloyd Beck, \u091c\u093f\u0928\u094d\u0939\u094b\u0902\u0928\u0947 1956 \u092e\u0947\u0902 Journal of Consulting Psychology \u092e\u0947\u0902 'A continuous performance test of brain damage' \u092a\u094d\u0930\u0915\u093e\u0936\u093f\u0924 \u0915\u093f\u092f\u093e\u0964 \u092c\u093e\u0926 \u0915\u0947 \u0924\u092e\u093e\u092e \u0930\u0942\u092a (Conners CPT, T.O.V.A., AX-CPT \u0914\u0930 \u0905\u0928\u094d\u092f) \u0909\u0928\u094d\u0939\u0940\u0902 \u0915\u0947 \u0935\u093f\u091a\u093e\u0930 \u0915\u0947 \u092c\u0926\u0932\u093e\u0935 \u0939\u0948\u0902, \u0905\u0932\u0917 \u0906\u0935\u093f\u0937\u094d\u0915\u093e\u0930 \u0928\u0939\u0940\u0902\u0964",methods:"\u090a\u092c\u093e\u090a \u0939\u093f\u0938\u094d\u0938\u0947 \u0915\u094b \u0939\u0940 \u0905\u0938\u0932\u0940 \u0907\u092e\u094d\u0924\u093f\u0939\u093e\u0928 \u092e\u093e\u0928\u0947\u0902: \u0915\u0920\u093f\u0928 \u0939\u093f\u0938\u094d\u0938\u093e \u092c\u0940\u091a \u0914\u0930 \u0905\u0902\u0924 \u0939\u0948, \u0936\u0941\u0930\u0941\u0906\u0924 \u0928\u0939\u0940\u0902\u0964 \u0926\u094c\u0921\u093c\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0926\u0947\u0928\u0947 \u0915\u0940 \u090f\u0915 \u0938\u094d\u0925\u093f\u0930 \u0930\u092b\u093c\u094d\u0924\u093e\u0930 \u092a\u0930 \u091f\u093f\u0915 \u091c\u093e\u090f\u0901, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u0905\u0927\u093f\u0915\u093e\u0902\u0936 \u0917\u0932\u0924\u093f\u092f\u093e\u0901 \u0909\u0938\u0940 'X' \u092a\u0930 \u0906\u0935\u0947\u0917\u0940 \u091f\u0948\u092a \u0939\u094b\u0924\u0940 \u0939\u0948\u0902 \u091c\u093f\u0938\u0947 \u0930\u094b\u0915\u0928\u093e \u0925\u093e\u0964 \u0905\u0926\u0932\u093e-\u092c\u0926\u0932\u0940 \u092a\u0930 \u0928\u091c\u093c\u0930 \u0930\u0916\u0947\u0902 \u2014 \u0905\u0917\u0930 \u0932\u0915\u094d\u0937\u094d\u092f \u091b\u0942\u091f \u0930\u0939\u0947 \u0939\u0948\u0902 \u0924\u094b \u0906\u092a \u0927\u094d\u092f\u093e\u0928 \u0938\u0947 \u092d\u091f\u0915 \u0917\u090f \u0939\u0948\u0902, \u0905\u0917\u0930 \u091b\u0932\u093e\u0935\u094b\u0902 \u092a\u0930 \u091f\u0948\u092a \u0915\u0930 \u0930\u0939\u0947 \u0939\u0948\u0902 \u0924\u094b \u0906\u092a \u091c\u093c\u0930\u0942\u0930\u0924 \u0938\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u092b\u0941\u0930\u094d\u0924\u0940\u0932\u0940 \u0909\u0901\u0917\u0932\u0940 \u0935\u093e\u0932\u0947 \u0939\u0948\u0902 \u2014 \u0914\u0930 \u091c\u094b \u092d\u0940 \u092a\u0915\u094d\u0937 \u091a\u0942\u0915 \u0930\u0939\u093e \u0939\u094b \u0909\u0938\u0947 \u0920\u0940\u0915 \u0915\u0940 \u0913\u0930 \u0927\u0915\u0947\u0932\u0947\u0902\u0964",duration:"\u0932\u0902\u092c\u0947 \u092e\u0948\u0930\u093e\u0925\u0928 \u0938\u0924\u094d\u0930\u094b\u0902 \u0938\u0947 \u091b\u094b\u091f\u0947 \u0914\u0930 \u092c\u093e\u0930-\u092c\u093e\u0930 \u0935\u093e\u0932\u0947 \u0938\u0924\u094d\u0930 \u092c\u0947\u0939\u0924\u0930 \u0939\u0948\u0902: \u090f\u0915 \u092c\u093e\u0930 \u092e\u0947\u0902 \u0915\u0930\u0940\u092c 8 \u0938\u0947 15 \u092e\u093f\u0928\u091f, \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u0915\u0941\u091b\u0947\u0915 \u092c\u093e\u0930, \u0938\u0924\u0930\u094d\u0915\u0924\u093e \u0915\u0940 \u0917\u093f\u0930\u093e\u0935\u091f \u0915\u094b \u092e\u0939\u0938\u0942\u0938 \u0915\u0930\u0928\u0947 \u0914\u0930 \u0909\u0938\u092e\u0947\u0902 \u0938\u0947 \u092a\u093e\u0930 \u0909\u0924\u0930\u0928\u093e \u0938\u0940\u0916\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0915\u093e\u092b\u093c\u0940 \u0939\u0948\u0964 \u0918\u0902\u091f\u0947 \u092d\u0930 \u092c\u0948\u0920\u0928\u0947 \u0938\u0947 \u092e\u0941\u0916\u094d\u092f\u0924\u0903 \u092f\u0939\u0940 \u092a\u0924\u093e \u091a\u0932\u0924\u093e \u0939\u0948 \u0915\u093f \u0939\u0930 \u0915\u093f\u0938\u0940 \u0915\u0940 \u091a\u094c\u0915\u0938\u0940 \u0922\u0932\u0924\u0940 \u0939\u0948 \u2014 \u090f\u0915 \u092c\u093e\u0930 \u0917\u093c\u094c\u0930 \u0915\u0930\u0928\u0947 \u0932\u093e\u092f\u0915, \u092a\u0930 \u0930\u094b\u091c\u093c \u0930\u091f\u0928\u0947 \u0932\u093e\u092f\u0915 \u0928\u0939\u0940\u0902\u0964",research:"\u0908\u092e\u093e\u0928\u0926\u093e\u0930 \u0938\u092c\u0942\u0924 \u0938\u0940\u092e\u093f\u0924 \u0939\u0948\u0902\u0964 CPT \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0922\u0902\u0917 \u0938\u0947 \u0928\u093f\u0930\u0902\u0924\u0930 \u0927\u094d\u092f\u093e\u0928 \u0914\u0930 \u0906\u0935\u0947\u0917-\u0928\u093f\u092f\u0902\u0924\u094d\u0930\u0923 \u0915\u094b \u0928\u093e\u092a\u0924\u093e \u0939\u0948, \u0914\u0930 \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0947 \u0938\u093e\u0925 \u0906\u092a \u0916\u0941\u0926 CPT \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902 \u2014 \u0915\u092e omissions \u0914\u0930 commissions, \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0938\u094d\u0925\u093f\u0930 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0917\u0924\u093f\u0964 \u092a\u0930 \u092f\u0939 \u0915\u093e\u092b\u093c\u0940 \u0939\u0926 \u0924\u0915 \u0935\u0939\u0940 \u0915\u093e\u0930\u094d\u092f-\u0935\u093f\u0936\u093f\u0937\u094d\u091f \u092b\u093c\u093e\u092f\u0926\u093e \u0939\u0948 \u091c\u093f\u0938\u0915\u0940 \u0909\u092e\u094d\u092e\u0940\u0926 \u0939\u094b\u0924\u0940 \u0939\u0948; \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0947 \u0927\u094d\u092f\u093e\u0928, \u0938\u094d\u0915\u0942\u0932 \u092f\u093e \u0915\u093e\u092e \u0915\u0947 \u092a\u094d\u0930\u0926\u0930\u094d\u0936\u0928, \u092f\u093e \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u092c\u0941\u0926\u094d\u0927\u093f \u0924\u0915 \u0935\u094d\u092f\u093e\u092a\u0915 '\u0938\u094d\u0925\u093e\u0928\u093e\u0902\u0924\u0930\u0923' \u0915\u092e\u091c\u093c\u094b\u0930 \u0914\u0930 \u0935\u093f\u0935\u093e\u0926\u093f\u0924 \u0939\u0948, \u0914\u0930 \u0915\u0941\u0932 \u092e\u093f\u0932\u093e\u0915\u0930 \u092c\u094d\u0930\u0947\u0928 \u091f\u094d\u0930\u0947\u0928\u093f\u0902\u0917 \u0938\u0947 \u0926\u0942\u0930-\u0938\u094d\u0925\u093e\u0928\u093e\u0902\u0924\u0930\u0923 \u0915\u0947 \u0926\u093e\u0935\u094b\u0902 \u0915\u093e \u0926\u094b\u0939\u0930\u093e\u0935 \u0930\u093f\u0915\u0949\u0930\u094d\u0921 \u0916\u093c\u0930\u093e\u092c \u0930\u0939\u093e \u0939\u0948\u0964 \u092f\u0939 \u092d\u0940 \u0927\u094d\u092f\u093e\u0928 \u0930\u0939\u0947 \u0915\u093f CPT \u0915\u094b \u090f\u0915 \u0906\u0915\u0932\u0928 \u0915\u0947 \u0924\u094c\u0930 \u092a\u0930 \u092c\u0928\u093e\u092f\u093e \u0917\u092f\u093e \u0925\u093e, \u0907\u0932\u093e\u091c \u0915\u0947 \u0924\u094c\u0930 \u092a\u0930 \u0928\u0939\u0940\u0902 \u2014 Pediatrics \u092e\u0947\u0902 2024 \u0915\u0940 \u090f\u0915 \u0935\u094d\u092f\u0935\u0938\u094d\u0925\u093f\u0924 \u0938\u092e\u0940\u0915\u094d\u0937\u093e \u092e\u0947\u0902 \u092a\u093e\u092f\u093e \u0917\u092f\u093e \u0915\u093f \u0905\u0915\u0947\u0932\u0947 ADHD \u091c\u093e\u0901\u091a\u0928\u0947 \u092e\u0947\u0902 CPT \u0915\u0940 \u0938\u091f\u0940\u0915\u0924\u093e \u0938\u0940\u092e\u093f\u0924 \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0915\u093f\u0938\u0940 \u092d\u0940 '\u0906\u092a\u0915\u093e \u0927\u094d\u092f\u093e\u0928 \u0920\u0940\u0915 \u0915\u0930 \u0926\u0947\u0917\u093e' \u0935\u093e\u0932\u0947 \u0935\u093e\u0926\u0947 \u0915\u094b \u0938\u093e\u0935\u0927\u093e\u0928\u0940 \u0938\u0947 \u0932\u0947\u0902\u0964",rec:"\u0907\u0938\u0915\u093e \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u092f\u0939 \u091c\u093e\u0928\u0928\u0947 \u0914\u0930 \u091c\u0932\u094d\u0926\u0940 \u092a\u0915\u0921\u093c\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0915\u0930\u0947\u0902 \u0915\u093f \u0906\u092a\u0915\u0940 \u0905\u092a\u0928\u0940 \u091a\u094c\u0915\u0938\u0940 \u0915\u093e \u0922\u0932\u0928\u093e \u0915\u0948\u0938\u093e \u092e\u0939\u0938\u0942\u0938 \u0939\u094b\u0924\u093e \u0939\u0948, \u0928 \u0915\u093f \u092d\u091f\u0915\u093e\u0935 \u0915\u0940 \u0926\u0935\u093e \u0915\u0947 \u0924\u094c\u0930 \u092a\u0930 \u2014 \u0907\u0938\u0947 \u0928\u0940\u0902\u0926 \u0914\u0930 \u0915\u092e \u0930\u0941\u0915\u093e\u0935\u091f\u094b\u0902 \u0915\u0947 \u0938\u093e\u0925 \u091c\u094b\u0921\u093c\u0947\u0902, \u091c\u094b \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0947 \u0927\u094d\u092f\u093e\u0928 \u0915\u094b \u0915\u0939\u0940\u0902 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0939\u093f\u0932\u093e\u0924\u0940 \u0939\u0948\u0902\u0964",faq:[["CPT \u090f\u0915 \u092a\u0930\u0940\u0915\u094d\u0937\u0923 \u0939\u0948 \u092f\u093e \u090f\u0915 \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u0905\u092d\u094d\u092f\u093e\u0938?","\u092e\u0942\u0932\u0924\u0903 \u0927\u094d\u092f\u093e\u0928 \u0915\u093e \u090f\u0915 \u0915\u094d\u0932\u093f\u0928\u093f\u0915\u0932 \u092a\u0930\u0940\u0915\u094d\u0937\u0923, \u0914\u0930 \u092f\u0939\u0940 \u0905\u092c \u092d\u0940 \u0907\u0938\u0915\u0940 \u092e\u0941\u0916\u094d\u092f \u092d\u0942\u092e\u093f\u0915\u093e \u0939\u0948\u0964 \u0907\u0938\u0947 \u0916\u0947\u0932 \u0915\u0940 \u0924\u0930\u0939 \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0930\u0928\u0947 \u0938\u0947 \u0907\u0938 \u0915\u093e\u0930\u094d\u092f \u092e\u0947\u0902 \u0906\u092a\u0915\u093e \u092a\u094d\u0930\u0926\u0930\u094d\u0936\u0928 \u092a\u0948\u0928\u093e \u0939\u094b \u0938\u0915\u0924\u093e \u0939\u0948, \u092a\u0930 \u0907\u0938\u0947 \u0915\u092d\u0940 \u0907\u0932\u093e\u091c \u0915\u0947 \u0924\u094c\u0930 \u092a\u0930 \u0928\u0939\u0940\u0902 \u092c\u0928\u093e\u092f\u093e \u0917\u092f\u093e, \u0907\u0938\u0932\u093f\u090f \u092f\u0939 \u0909\u092e\u094d\u092e\u0940\u0926 \u0928 \u0915\u0930\u0947\u0902 \u0915\u093f \u092f\u0939 \u092d\u091f\u0915\u093e\u0935 \u0915\u094b '\u0920\u0940\u0915' \u0915\u0930 \u0926\u0947\u0917\u093e\u0964"],["\u0915\u094d\u092f\u093e \u092f\u0939 ADHD \u0915\u0940 \u091c\u093e\u0901\u091a \u0915\u0930 \u0926\u0947\u0924\u093e \u0939\u0948?","\u0905\u0915\u0947\u0932\u0947 \u0928\u0939\u0940\u0902\u0964 CPT \u0938\u094d\u0915\u094b\u0930 \u0915\u093f\u0938\u0940 \u091a\u093f\u0915\u093f\u0924\u094d\u0938\u0915 \u0915\u0940 \u0927\u094d\u092f\u093e\u0928 \u0914\u0930 \u0906\u0935\u0947\u0917\u0936\u0940\u0932\u0924\u093e \u0915\u0940 \u0924\u0938\u094d\u0935\u0940\u0930 \u0915\u094b \u0938\u0939\u093e\u0930\u093e \u0926\u0947 \u0938\u0915\u0924\u0947 \u0939\u0948\u0902, \u092a\u0930 2024 \u0915\u0940 \u090f\u0915 \u0935\u094d\u092f\u0935\u0938\u094d\u0925\u093f\u0924 \u0938\u092e\u0940\u0915\u094d\u0937\u093e \u092e\u0947\u0902 \u092a\u093e\u092f\u093e \u0917\u092f\u093e \u0915\u093f \u0905\u0915\u0947\u0932\u0947 \u0907\u0928\u0915\u0940 \u0928\u0948\u0926\u093e\u0928\u093f\u0915 \u0938\u091f\u0940\u0915\u0924\u093e \u0938\u0940\u092e\u093f\u0924 \u0939\u0948 \u2014 \u091c\u093e\u0901\u091a \u0915\u0947 \u0932\u093f\u090f \u092a\u0942\u0930\u093e \u0906\u0915\u0932\u0928 \u091a\u093e\u0939\u093f\u090f, \u0915\u094b\u0908 \u090f\u0915 \u0938\u094d\u0915\u094b\u0930 \u0928\u0939\u0940\u0902\u0964"],["\u091c\u093f\u0924\u0928\u093e \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0926\u0947\u0930 \u0916\u0947\u0932\u0924\u093e \u0939\u0942\u0901, \u0909\u0924\u0928\u093e \u0916\u093c\u0930\u093e\u092c \u0915\u094d\u092f\u094b\u0902 \u0939\u094b\u0924\u093e \u091c\u093e\u0924\u093e \u0939\u0942\u0901?","\u092f\u0939 \u0938\u0924\u0930\u094d\u0915\u0924\u093e-\u0939\u094d\u0930\u093e\u0938 (vigilance decrement) \u0939\u0948 \u2014 \u0928\u0940\u0930\u0938, \u0915\u092e-\u0918\u091f\u0928\u093e \u0935\u093e\u0932\u0947 \u0915\u093e\u0930\u094d\u092f\u094b\u0902 \u092a\u0930 \u0928\u093f\u0930\u0902\u0924\u0930 \u0927\u094d\u092f\u093e\u0928 \u0938\u092e\u092f \u0915\u0947 \u0938\u093e\u0925 \u0938\u094d\u0935\u092d\u093e\u0935\u0924\u0903 \u0922\u0932\u0924\u093e \u0939\u0948\u0964 \u092f\u0939\u0940 \u0935\u0939 \u091a\u0940\u091c\u093c \u0939\u0948 \u091c\u093f\u0938\u0947 \u0909\u091c\u093e\u0917\u0930 \u0915\u0930\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f CPT \u092c\u0928\u093e \u0925\u093e, \u0907\u0938\u0932\u093f\u090f \u0905\u092a\u0928\u0940 \u091a\u094c\u0915\u0938\u0940 \u0915\u093e \u0922\u0932\u0928\u093e \u0917\u093c\u094c\u0930 \u0915\u0930\u0928\u093e \u092d\u0940 \u092e\u0915\u093c\u0938\u0926 \u0915\u093e \u0939\u093f\u0938\u094d\u0938\u093e \u0939\u0948\u0964"]],variants:"\u0915\u094d\u0932\u093e\u0938\u093f\u0915 X-CPT ('X' \u0915\u094b \u091b\u094b\u0921\u093c\u0915\u0930 \u0938\u092c \u092a\u0930 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e) \u0914\u0930 AX-CPT (\u0938\u093f\u0930\u094d\u092b\u093c \u0924\u092c \u091c\u092c 'A' \u0915\u0947 \u092c\u093e\u0926 'X' \u0906\u090f) \u0907\u0938\u0915\u0947 \u092e\u0941\u0916\u094d\u092f \u0930\u0942\u092a \u0939\u0948\u0902; Identical Pairs \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0906\u092a\u0938\u0947 \u0924\u092c \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u092e\u093e\u0901\u0917\u0924\u093e \u0939\u0948 \u091c\u092c \u0932\u0917\u093e\u0924\u093e\u0930 \u0926\u094b \u0909\u0926\u094d\u0926\u0940\u092a\u0928 \u092e\u0947\u0932 \u0916\u093e\u090f\u0901\u0964 \u0907\u0928\u0915\u0947 \u0905\u0932\u093e\u0935\u093e, \u0915\u094d\u0932\u093f\u0928\u093f\u0915\u0932 \u0915\u093f\u091f \u0936\u094d\u0930\u0935\u0923-\u0927\u093e\u0930\u093e\u090f\u0901, \u092e\u093f\u0936\u094d\u0930\u093f\u0924 \u0926\u0943\u0936\u094d\u092f-\u0914\u0930-\u0927\u094d\u0935\u0928\u093f \u0938\u0902\u0938\u094d\u0915\u0930\u0923, \u0935\u093f\u0930\u0932-\u0932\u0915\u094d\u0937\u094d\u092f \u0935\u093e\u0932\u0947 \u092c\u094d\u0932\u0949\u0915 (\u091c\u094b \u0905\u0938\u093e\u0935\u0927\u093e\u0928\u0940 \u0915\u094b \u0909\u092d\u093e\u0930\u0924\u0947 \u0939\u0948\u0902) \u0914\u0930 \u092c\u093e\u0930\u0902\u092c\u093e\u0930-\u0932\u0915\u094d\u0937\u094d\u092f \u0935\u093e\u0932\u0947 \u092c\u094d\u0932\u0949\u0915 (\u091c\u094b \u0906\u0935\u0947\u0917\u0940 \u0917\u0932\u0924\u093f\u092f\u093e\u0901 \u0909\u0915\u0938\u093e\u0924\u0947 \u0939\u0948\u0902) \u091c\u094b\u0921\u093c \u0926\u0947\u0924\u0947 \u0939\u0948\u0902\u0964"},zh:{about:"CPT \u662f\u4e00\u9879\u8b66\u6212\u4efb\u52a1\u3002\u4e00\u957f\u4e32\u5355\u8c03\u7684\u5b57\u6bcd\u4e00\u4e2a\u63a5\u4e00\u4e2a\u5730\u95ea\u8fc7\uff0c\u4f60\u7684\u4efb\u52a1\u662f\u5bf9\u76ee\u6807\u505a\u51fa\u53cd\u5e94\uff0c\u800c\u5bf9\u5176\u4f59\u4e00\u5207\u90fd\u8981\u514b\u5236\u2014\u2014\u6700\u5e38\u89c1\u7684\u662f\u9664\u4e86\u300cX\u300d\u4e4b\u5916\u6bcf\u4e2a\u5b57\u6bcd\u90fd\u70b9\u4e00\u4e0b\uff0c\u6216\u8005\u53ea\u5728\u67d0\u4e2a\u300c\u7ebf\u7d22\u300d\u5b57\u6bcd\u540e\u9762\u8ddf\u7740\u7279\u5b9a\u300c\u63a2\u9488\u300d\u65f6\u624d\u70b9\u3002\u91cd\u70b9\u4e0d\u5728\u4e8e\u5feb\uff0c\u800c\u5728\u4e8e\u5f53\u51e0\u4e4e\u4ec0\u4e48\u90fd\u6ca1\u53d1\u751f\u65f6\uff0c\u4ecd\u7136\u4fdd\u6301\u300c\u5728\u7ebf\u300d\u3002",benefit:"\u5b83\u8bad\u7ec3\u6301\u7eed\u6027\u6ce8\u610f\u548c\u53cd\u5e94\u6291\u5236\u2014\u2014\u4e5f\u5c31\u662f\u4f60\u5728\u4e00\u6761\u4e4f\u5473\u3001\u4f4e\u4e8b\u4ef6\u7684\u5b57\u6bcd\u6d41\u91cc\u6301\u7eed\u76d1\u63a7\u800c\u4e0d\u8d70\u795e\u7684\u80fd\u529b\uff0c\u4ee5\u53ca\u5728\u4e0d\u8be5\u6309\u65f6\u538b\u4f4f\u6309\u952e\u51b2\u52a8\u7684\u80fd\u529b\u3002\u7528 CPT \u7684\u8bdd\u6765\u8bf4\uff0c\u8fd9\u610f\u5473\u7740\u66f4\u5c11\u7684\u6f0f\u62a5\uff08\u9057\u6f0f\u76ee\u6807\uff09\u3001\u66f4\u5c11\u7684\u5bf9\u5e72\u6270\u9879\u7684\u51b2\u52a8\u6309\u952e\uff08\u9519\u6309\uff09\uff0c\u4ee5\u53ca\u5728\u6f2b\u957f\u8fc7\u7a0b\u4e2d\u66f4\u7a33\u5b9a\u7684\u53cd\u5e94\u65f6\u3002",history:"\u5b83\u8d77\u521d\u662f\u4e00\u9879\u4e34\u5e8a\u6d4b\u9a8c\uff0c\u800c\u975e\u6e38\u620f\u30021956 \u5e74\uff0c\u7f8e\u56fd\u56fd\u5bb6\u5fc3\u7406\u536b\u751f\u7814\u7a76\u9662\u7684\u4e00\u4e2a\u56e2\u961f\u9020\u4e86\u4e00\u53f0\u88c5\u7f6e\uff0c\u628a\u5b57\u6bcd\u95ea\u73b0\u5728\u4e00\u4e2a\u65cb\u8f6c\u9f13\u4e0a\uff0c\u7528\u6765\u6d4b\u91cf\u8111\u635f\u4f24\u60a3\u8005\u2014\u2014\u5c24\u5176\u662f\u5c0f\u53d1\u4f5c\u766b\u75eb\u60a3\u8005\u2014\u2014\u80fd\u5426\u957f\u65f6\u95f4\u4fdd\u6301\u6ce8\u610f\u3002\u4ece 1970 \u5e74\u4ee3\u8d77\uff0c\u5b83\u6210\u4e3a\u7814\u7a76\u6ce8\u610f\uff08\u4ee5\u53ca\u540e\u6765\u8bc4\u4f30 ADHD\uff09\u7684\u6807\u51c6\u5de5\u5177\u4e4b\u4e00\uff0c\u5e76\u884d\u751f\u51fa\u5728\u5168\u7403\u8bca\u6240\u4f7f\u7528\u7684\u5404\u79cd\u8ba1\u7b97\u673a\u5316\u7248\u672c\u3002",creator:"\u5b83\u6709\u660e\u786e\u7684\u8d77\u6e90\uff1aHaldor Rosvold\u3001Allan Mirsky\u3001Irwin Sarason\u3001Edwin Bransome \u548c Lloyd Beck\uff0c\u4ed6\u4eec\u4e8e 1956 \u5e74\u5728\u300aJournal of Consulting Psychology\u300b\u4e0a\u53d1\u8868\u4e86\u300aA continuous performance test of brain damage\u300b\u3002\u540e\u6765\u4f17\u591a\u7684\u5f62\u5f0f\uff08Conners CPT\u3001T.O.V.A.\u3001AX-CPT \u7b49\uff09\u90fd\u662f\u5bf9\u4ed6\u4eec\u8fd9\u4e00\u6784\u60f3\u7684\u53d8\u4f53\uff0c\u800c\u975e\u5404\u81ea\u72ec\u7acb\u7684\u53d1\u660e\u3002",methods:"\u628a\u90a3\u6bb5\u65e0\u804a\u7684\u8fc7\u7a0b\u5f53\u6210\u771f\u6b63\u7684\u8003\u9a8c\uff1a\u96be\u7684\u662f\u4e2d\u6bb5\u548c\u672b\u6bb5\uff0c\u800c\u4e0d\u662f\u5f00\u5934\u3002\u786e\u5b9a\u4e00\u4e2a\u7a33\u5b9a\u7684\u5e94\u7b54\u8282\u594f\uff0c\u800c\u4e0d\u8981\u62a2\u5feb\uff0c\u56e0\u4e3a\u5927\u591a\u6570\u9519\u8bef\u90fd\u662f\u5bf9\u672c\u8be5\u538b\u4f4f\u7684\u300cX\u300d\u7684\u51b2\u52a8\u6309\u952e\u3002\u76ef\u4f4f\u8fd9\u4e2a\u53d6\u820d\u2014\u2014\u5982\u679c\u4f60\u5728\u6f0f\u6389\u76ee\u6807\uff0c\u8bf4\u660e\u4f60\u5df2\u7ecf\u8d70\u795e\uff1b\u5982\u679c\u4f60\u5728\u6309\u5e72\u6270\u9879\uff0c\u8bf4\u660e\u4f60\u592a\u5bb9\u6613\u6263\u6273\u673a\u2014\u2014\u54ea\u4e00\u8fb9\u5728\u51fa\u95ee\u9898\u5c31\u5f80\u54ea\u4e00\u8fb9\u5fae\u8c03\u3002",duration:"\u77ed\u800c\u9891\u7e41\u80dc\u8fc7\u9a6c\u62c9\u677e\u5f0f\u4e45\u5750\uff1a\u6bcf\u6b21\u5927\u7ea6 8 \u5230 15 \u5206\u949f\uff0c\u6bcf\u5468\u51e0\u6b21\uff0c\u5c31\u8db3\u4ee5\u611f\u53d7\u5230\u90a3\u79cd\u8b66\u6212\u5ea6\u7684\u4e0b\u6ed1\u5e76\u5b66\u4f1a\u625b\u8fc7\u53bb\u3002\u5750\u4e0a\u4e00\u4e2a\u5c0f\u65f6\u4e3b\u8981\u53ea\u4f1a\u6559\u4f1a\u4f60\u300c\u6bcf\u4e2a\u4eba\u90fd\u4f1a\u8870\u9000\u300d\u2014\u2014\u8fd9\u4e00\u70b9\u503c\u5f97\u4f53\u4f1a\u4e00\u6b21\uff0c\u4f46\u4e0d\u503c\u5f97\u5929\u5929\u53bb\u78e8\u3002",research:"\u8bda\u5b9e\u7684\u8bc1\u636e\u8303\u56f4\u5f88\u7a84\u3002CPT \u80fd\u53ef\u9760\u5730\u6d4b\u91cf\u6301\u7eed\u6027\u6ce8\u610f\u548c\u51b2\u52a8\u63a7\u5236\uff0c\u800c\u968f\u7740\u7ec3\u4e60\uff0c\u4f60\u4f1a\u5728 CPT \u672c\u8eab\u4e0a\u53d8\u597d\u2014\u2014\u66f4\u5c11\u7684\u9057\u6f0f\u548c\u9519\u6309\u3001\u66f4\u7a33\u5b9a\u7684\u53cd\u5e94\u65f6\u3002\u4f46\u8fd9\u57fa\u672c\u4e0a\u5c31\u662f\u4f60\u80fd\u9884\u6599\u5230\u7684\u3001\u4efb\u52a1\u7279\u6709\u7684\u6536\u76ca\uff1b\u81f3\u4e8e\u5e7f\u6cdb\u300c\u8fc1\u79fb\u300d\u5230\u65e5\u5e38\u4e13\u6ce8\u3001\u5b66\u4e1a\u6216\u5de5\u4f5c\u8868\u73b0\uff0c\u4e43\u81f3\u4e00\u822c\u667a\u529b\uff0c\u8bc1\u636e\u90fd\u5f88\u5f31\u3001\u6709\u4e89\u8bae\uff0c\u800c\u6574\u4f53\u800c\u8a00\u5927\u8111\u8bad\u7ec3\u7684\u300c\u8fdc\u8fc1\u79fb\u300d\u8bf4\u6cd5\u5728\u590d\u73b0\u4e0a\u8bb0\u5f55\u5f88\u5dee\u3002\u8fd8\u8981\u6ce8\u610f\uff0cCPT \u662f\u4f5c\u4e3a\u4e00\u79cd\u8bc4\u4f30\u3001\u800c\u975e\u4e00\u79cd\u6cbb\u7597\u88ab\u9020\u51fa\u6765\u7684\u2014\u20142024 \u5e74\u300aPediatrics\u300b\u4e0a\u7684\u4e00\u7bc7\u7cfb\u7edf\u7efc\u8ff0\u53d1\u73b0\uff0c\u5355\u51ed CPT \u8bca\u65ad ADHD \u7684\u51c6\u786e\u5ea6\u6709\u9650\uff0c\u6240\u4ee5\u5bf9\u4efb\u4f55\u300c\u4fee\u597d\u4f60\u6ce8\u610f\u529b\u300d\u7684\u627f\u8bfa\u90fd\u8981\u8c28\u614e\u3002",rec:"\u7528\u5b83\u6765\u8ba4\u8bc6\u81ea\u5df1\u300c\u8d70\u795e\u300d\u65f6\u662f\u4ec0\u4e48\u611f\u89c9\u3001\u5e76\u53ca\u65e9\u6293\u4f4f\u5b83\uff0c\u800c\u4e0d\u662f\u628a\u5b83\u5f53\u4f5c\u5206\u5fc3\u7684\u89e3\u836f\u2014\u2014\u628a\u5b83\u548c\u5145\u8db3\u7761\u7720\u3001\u51cf\u5c11\u6253\u6270\u642d\u914d\u8d77\u6765\uff0c\u8fd9\u4e24\u6837\u5bf9\u65e5\u5e38\u6ce8\u610f\u529b\u7684\u6539\u5584\u8981\u5927\u5f97\u591a\u3002",faq:[["CPT \u662f\u6d4b\u9a8c\u8fd8\u662f\u8bad\u7ec3\u7ec3\u4e60\uff1f","\u5b83\u6700\u521d\u662f\u4e00\u9879\u6ce8\u610f\u7684\u4e34\u5e8a\u6d4b\u9a8c\uff0c\u81f3\u4eca\u4ecd\u4e3b\u8981\u626e\u6f14\u8fd9\u4e00\u89d2\u8272\u3002\u50cf\u73a9\u6e38\u620f\u4e00\u6837\u7ec3\u5b83\u80fd\u78e8\u5feb\u4f60\u5728\u8be5\u4efb\u52a1\u4e0a\u7684\u8868\u73b0\uff0c\u4f46\u5b83\u4ece\u6765\u4e0d\u662f\u4f5c\u4e3a\u6cbb\u7597\u8bbe\u8ba1\u7684\uff0c\u6240\u4ee5\u522b\u6307\u671b\u5b83\u80fd\u300c\u6cbb\u597d\u300d\u5206\u5fc3\u3002"],["\u5b83\u80fd\u8bca\u65ad ADHD \u5417\uff1f","\u5355\u51ed\u5b83\u4e0d\u884c\u3002CPT \u5206\u6570\u53ef\u4ee5\u652f\u6301\u4e34\u5e8a\u533b\u751f\u5bf9\u6ce8\u610f\u529b\u548c\u51b2\u52a8\u6027\u7684\u5224\u65ad\uff0c\u4f46 2024 \u5e74\u7684\u4e00\u7bc7\u7cfb\u7edf\u7efc\u8ff0\u53d1\u73b0\uff0c\u5b83\u5355\u72ec\u4f7f\u7528\u65f6\u7684\u8bca\u65ad\u51c6\u786e\u5ea6\u6709\u9650\u2014\u2014\u8bca\u65ad\u9700\u8981\u4e00\u6b21\u5b8c\u6574\u7684\u8bc4\u4f30\uff0c\u800c\u975e\u5355\u4e00\u5206\u6570\u3002"],["\u4e3a\u4ec0\u4e48\u6211\u73a9\u5f97\u8d8a\u4e45\u53cd\u800c\u8d8a\u5dee\uff1f","\u8fd9\u5c31\u662f\u8b66\u6212\u8870\u51cf\u2014\u2014\u5728\u4e4f\u5473\u3001\u4f4e\u4e8b\u4ef6\u7684\u4efb\u52a1\u4e0a\uff0c\u6301\u7eed\u6027\u6ce8\u610f\u4f1a\u968f\u65f6\u95f4\u81ea\u7136\u4e0b\u6ed1\u3002\u8fd9\u6b63\u662f CPT \u88ab\u9020\u51fa\u6765\u8981\u66b4\u9732\u7684\u4e1c\u897f\uff0c\u6240\u4ee5\u5bdf\u89c9\u5230\u81ea\u5df1\u7684\u8870\u9000\u672c\u8eab\u5c31\u662f\u8981\u70b9\u4e4b\u4e00\u3002"]],variants:"\u7ecf\u5178\u7684 X-CPT\uff08\u9664\u300cX\u300d\u5916\u90fd\u53cd\u5e94\uff09\u548c AX-CPT\uff08\u4ec5\u5f53\u300cA\u300d\u540e\u8ddf\u300cX\u300d\u65f6\u624d\u53cd\u5e94\uff09\u662f\u6838\u5fc3\u5f62\u5f0f\uff1b\u76f8\u540c\u914d\u5bf9\uff08Identical Pairs\uff09\u7248\u8981\u6c42\u4f60\u5728\u8fde\u7eed\u4e24\u4e2a\u523a\u6fc0\u76f8\u540c\u65f6\u505a\u51fa\u53cd\u5e94\u3002\u9664\u6b64\u4e4b\u5916\uff0c\u4e34\u5e8a\u5957\u4ef6\u8fd8\u4f1a\u52a0\u5165\u542c\u89c9\u6d41\u3001\u89c6\u542c\u6df7\u5408\u7248\u3001\u7528\u6765\u8bf1\u53d1\u758f\u5ffd\u7684\u4f4e\u9891\u76ee\u6807\u6bb5\uff0c\u4ee5\u53ca\u7528\u6765\u8bf1\u53d1\u51b2\u52a8\u9519\u8bef\u7684\u9ad8\u9891\u76ee\u6807\u6bb5\u3002"}},"digit-span":{ru:{about:"\u0412 Digit Span \u043d\u0430 \u044d\u043a\u0440\u0430\u043d\u0435 \u043f\u043e \u043e\u0434\u043d\u043e\u0439 \u043f\u043e\u044f\u0432\u043b\u044f\u044e\u0442\u0441\u044f \u0446\u0438\u0444\u0440\u044b, \u0430 \u0437\u0430\u0442\u0435\u043c \u043d\u0443\u0436\u043d\u043e \u0432\u0432\u0435\u0441\u0442\u0438 \u0432\u0441\u044e \u043f\u043e\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c \u043e\u0431\u0440\u0430\u0442\u043d\u043e. \u0412 \u043f\u0440\u044f\u043c\u043e\u043c \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u0435 \u0432\u044b \u043f\u043e\u0432\u0442\u043e\u0440\u044f\u0435\u0442\u0435 \u0435\u0451 \u0432 \u0442\u043e\u043c \u0436\u0435 \u043f\u043e\u0440\u044f\u0434\u043a\u0435, \u0432 \u043e\u0431\u0440\u0430\u0442\u043d\u043e\u043c \u2014 \u0437\u0430\u0434\u043e\u043c \u043d\u0430\u043f\u0435\u0440\u0451\u0434. \u041f\u043e\u0441\u043b\u0435 \u043a\u0430\u0436\u0434\u043e\u0433\u043e \u0432\u0435\u0440\u043d\u043e\u0433\u043e \u043e\u0442\u0432\u0435\u0442\u0430 \u0446\u0435\u043f\u043e\u0447\u043a\u0430 \u0443\u0434\u043b\u0438\u043d\u044f\u0435\u0442\u0441\u044f \u043d\u0430 \u043e\u0434\u043d\u0443 \u0446\u0438\u0444\u0440\u0443, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u0438\u0433\u0440\u0430 \u043f\u043e\u0441\u0442\u043e\u044f\u043d\u043d\u043e \u043f\u043e\u0434\u0432\u043e\u0434\u0438\u0442 \u0432\u0430\u0441 \u043a \u0441\u0430\u043c\u043e\u043c\u0443 \u043f\u0440\u0435\u0434\u0435\u043b\u0443 \u0442\u043e\u0433\u043e, \u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0432\u044b \u0441\u043f\u043e\u0441\u043e\u0431\u043d\u044b \u0443\u0434\u0435\u0440\u0436\u0430\u0442\u044c.",benefit:"\u0422\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442\u0441\u044f \u0432\u0435\u0440\u0431\u0430\u043b\u044c\u043d\u0430\u044f \u043a\u0440\u0430\u0442\u043a\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u0430\u044f \u0438 \u0440\u0430\u0431\u043e\u0447\u0430\u044f \u043f\u0430\u043c\u044f\u0442\u044c: \u0441\u043a\u043e\u043b\u044c\u043a\u043e \u044d\u043b\u0435\u043c\u0435\u043d\u0442\u043e\u0432 \u0432\u044b \u043c\u043e\u0436\u0435\u0442\u0435 \u0434\u0435\u0440\u0436\u0430\u0442\u044c \u0430\u043a\u0442\u0438\u0432\u043d\u044b\u043c\u0438 \u043e\u0434\u043d\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u043e, \u0430 \u0432 \u043e\u0431\u0440\u0430\u0442\u043d\u043e\u043c \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u0435 \u2014 \u0435\u0449\u0451 \u0438 \u0441\u043f\u043e\u0441\u043e\u0431\u043d\u043e\u0441\u0442\u044c \u043d\u0435 \u043f\u0440\u043e\u0441\u0442\u043e \u0445\u0440\u0430\u043d\u0438\u0442\u044c \u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b, \u0430 \u043f\u0435\u0440\u0435\u0431\u0438\u0440\u0430\u0442\u044c \u0435\u0433\u043e \u0432 \u0443\u043c\u0435.",history:"\u0417\u0430\u0434\u0430\u043d\u0438\u0435 \u0432\u044b\u0440\u043e\u0441\u043b\u043e \u0438\u0437 \u0440\u0430\u043d\u043d\u0435\u0439 \u044d\u043a\u0441\u043f\u0435\u0440\u0438\u043c\u0435\u043d\u0442\u0430\u043b\u044c\u043d\u043e\u0439 \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u0438, \u0433\u0434\u0435 \u0438\u0437\u043c\u0435\u0440\u0435\u043d\u0438\u0435 \u0433\u0440\u0430\u043d\u0438\u0446 \u043f\u0430\u043c\u044f\u0442\u0438 \u0431\u044b\u043b\u043e \u043e\u0434\u043d\u0438\u043c \u0438\u0437 \u0433\u043b\u0430\u0432\u043d\u044b\u0445 \u0432\u043e\u043f\u0440\u043e\u0441\u043e\u0432. \u0412 \u043d\u0430\u0447\u0430\u043b\u0435 XX \u0432\u0435\u043a\u0430 \u043e\u043d\u043e \u0432\u043e\u0448\u043b\u043e \u0432 \u043f\u0435\u0440\u0432\u044b\u0435 \u0441\u0442\u0430\u043d\u0434\u0430\u0440\u0442\u0438\u0437\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u044b\u0435 \u0442\u0435\u0441\u0442\u044b \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442\u0430 \u0438 \u0441 \u0442\u0435\u0445 \u043f\u043e\u0440 \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0435\u0442\u0441\u044f \u0432 \u043a\u043b\u0438\u043d\u0438\u043a\u0435, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u043f\u043e\u0447\u0442\u0438 \u043a\u0430\u0436\u0434\u044b\u0439, \u043a\u0442\u043e \u043f\u0440\u043e\u0445\u043e\u0434\u0438\u043b \u0444\u043e\u0440\u043c\u0430\u043b\u044c\u043d\u0443\u044e \u043e\u0446\u0435\u043d\u043a\u0443 IQ \u0438\u043b\u0438 \u043f\u0430\u043c\u044f\u0442\u0438, \u0434\u0435\u043b\u0430\u043b \u0442\u043e\u0442 \u0438\u043b\u0438 \u0438\u043d\u043e\u0439 \u0435\u0433\u043e \u0432\u0430\u0440\u0438\u0430\u043d\u0442.",creator:"\u041c\u0435\u0442\u043e\u0434 \u043f\u0440\u0438\u043f\u0438\u0441\u044b\u0432\u0430\u044e\u0442 \u0431\u0440\u0438\u0442\u0430\u043d\u0441\u043a\u043e\u043c\u0443 \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0443 \u0414\u0436\u043e\u0437\u0435\u0444\u0443 \u0414\u0436\u0435\u0439\u043a\u043e\u0431\u0441\u0443, \u043e\u043f\u0443\u0431\u043b\u0438\u043a\u043e\u0432\u0430\u0432\u0448\u0435\u043c\u0443 \u0435\u0433\u043e \u0432 1887 \u0433\u043e\u0434\u0443, \u0447\u0442\u043e\u0431\u044b \u0438\u0437\u043c\u0435\u0440\u0438\u0442\u044c, \u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0438\u043d\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u0438 \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0435\u0442 \u043a\u0440\u0430\u0442\u043a\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u0430\u044f \u043f\u0430\u043c\u044f\u0442\u044c. \u041f\u043e\u0437\u0436\u0435 \u043e\u043d \u0432\u043e\u0448\u0451\u043b \u0432 \u0448\u043a\u0430\u043b\u0443 \u0411\u0438\u043d\u0435-\u0421\u0438\u043c\u043e\u043d\u0430, \u0430 \u0437\u0430\u0442\u0435\u043c \u0432 \u0448\u043a\u0430\u043b\u044b \u0412\u0435\u043a\u0441\u043b\u0435\u0440\u0430 (WAIS \u0438 WISC), \u0433\u0434\u0435 \u043f\u0440\u044f\u043c\u043e\u0439, \u043e\u0431\u0440\u0430\u0442\u043d\u044b\u0439 \u0438 \u0431\u043e\u043b\u0435\u0435 \u043f\u043e\u0437\u0434\u043d\u0438\u0439 \u043f\u043e\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u044c\u043d\u044b\u0439 \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u044b \u0434\u043e \u0441\u0438\u0445 \u043f\u043e\u0440 \u043e\u0441\u0442\u0430\u044e\u0442\u0441\u044f \u0441\u0442\u0430\u043d\u0434\u0430\u0440\u0442\u043d\u044b\u043c\u0438 \u0441\u0443\u0431\u0442\u0435\u0441\u0442\u0430\u043c\u0438.",methods:"\u0413\u043b\u0430\u0432\u043d\u044b\u0439 \u043f\u0440\u0438\u0451\u043c \u2014 \u0433\u0440\u0443\u043f\u043f\u0438\u0440\u043e\u0432\u043a\u0430: \u0434\u043b\u0438\u043d\u043d\u0443\u044e \u0441\u0442\u0440\u043e\u043a\u0443 \u0440\u0430\u0437\u0431\u0438\u0432\u0430\u044e\u0442 \u043d\u0430 \u043f\u0430\u0440\u044b \u0438\u043b\u0438 \u0442\u0440\u043e\u0439\u043a\u0438 (4 7 1 9 3 8 \u043f\u0440\u0435\u0432\u0440\u0430\u0449\u0430\u0435\u0442\u0441\u044f \u0432 47, 19, 38), \u0438 \u0442\u043e\u0433\u0434\u0430 \u0432\u044b \u0434\u0435\u0440\u0436\u0438\u0442\u0435 \u0442\u0440\u0438 \u0431\u043b\u043e\u043a\u0430 \u0432\u043c\u0435\u0441\u0442\u043e \u0448\u0435\u0441\u0442\u0438. \u041f\u043e\u043c\u043e\u0433\u0430\u0435\u0442 \u043f\u0440\u043e\u0433\u043e\u0432\u0430\u0440\u0438\u0432\u0430\u0442\u044c \u043f\u043e\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c \u043f\u0440\u043e \u0441\u0435\u0431\u044f \u043f\u043e \u043c\u0435\u0440\u0435 \u043f\u043e\u044f\u0432\u043b\u0435\u043d\u0438\u044f \u0438 \u0437\u0430\u0434\u0430\u0432\u0430\u0442\u044c \u0435\u0439 \u0440\u0438\u0442\u043c, \u0430 \u0434\u043b\u044f \u043e\u0431\u0440\u0430\u0442\u043d\u043e\u0433\u043e \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u0430 \u0447\u0430\u0441\u0442\u043e \u043f\u0440\u043e\u0449\u0435 \u043c\u044b\u0441\u043b\u0435\u043d\u043d\u043e \u0443\u0432\u0438\u0434\u0435\u0442\u044c \u0446\u0438\u0444\u0440\u044b \u0437\u0430\u043f\u0438\u0441\u0430\u043d\u043d\u044b\u043c\u0438 \u0438 \u0441\u0447\u0438\u0442\u0430\u0442\u044c \u0438\u0445 \u0441 \u043a\u043e\u043d\u0446\u0430.",duration:"\u041a\u043e\u0440\u043e\u0442\u043a\u0438\u0435 \u0447\u0430\u0441\u0442\u044b\u0435 \u043f\u043e\u0434\u0445\u043e\u0434\u044b \u043f\u043e\u043b\u0435\u0437\u043d\u0435\u0435 \u0434\u043e\u043b\u0433\u0438\u0445: 5\u201310 \u043c\u0438\u043d\u0443\u0442 \u0432 \u0434\u0435\u043d\u044c \u0434\u043e\u0441\u0442\u0430\u0442\u043e\u0447\u043d\u043e, \u0432\u0435\u0434\u044c \u043a\u0430\u043a \u0442\u043e\u043b\u044c\u043a\u043e \u0446\u0435\u043f\u043e\u0447\u043a\u0430 \u043f\u0440\u0435\u0432\u044b\u0448\u0430\u0435\u0442 \u0432\u0430\u0448 \u043f\u0440\u0435\u0434\u0435\u043b, \u0432\u044b \u0443\u0436\u0435 \u043d\u0435 \u0443\u0447\u0438\u0442\u0435\u0441\u044c, \u0430 \u043a\u043e\u043f\u0438\u0442\u0435 \u043e\u0448\u0438\u0431\u043a\u0438. \u041d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u043f\u043e\u0434\u0445\u043e\u0434\u043e\u0432 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e \u2014 \u0438 \u0437\u0430 \u043f\u0430\u0440\u0443 \u043d\u0435\u0434\u0435\u043b\u044c \u0434\u043e\u0441\u0442\u0443\u043f\u043d\u0430\u044f \u0434\u043b\u0438\u043d\u0430 \u0437\u0430\u043c\u0435\u0442\u043d\u043e \u043f\u043e\u0434\u0440\u0430\u0441\u0442\u0430\u0435\u0442.",research:"\u041d\u0430\u0434\u0451\u0436\u043d\u043e \u0434\u043e\u043a\u0430\u0437\u0430\u043d\u043e \u043b\u0438\u0448\u044c \u0443\u0437\u043a\u043e\u0435: \u0441 \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u043e\u0439 \u0432\u044b \u043b\u0443\u0447\u0448\u0435 \u0441\u043f\u0440\u0430\u0432\u043b\u044f\u0435\u0442\u0435\u0441\u044c \u0438\u043c\u0435\u043d\u043d\u043e \u0441 \u044d\u0442\u0438\u043c \u0437\u0430\u0434\u0430\u043d\u0438\u0435\u043c, \u0438 \u0438\u0437\u043c\u0435\u0440\u0435\u043d\u043d\u044b\u0439 \u043e\u0431\u044a\u0451\u043c \u043d\u0430 \u043f\u043e\u0445\u043e\u0436\u0438\u0445 \u0442\u0435\u0441\u0442\u0430\u0445 \u043d\u0430 \u0437\u0430\u043f\u043e\u043c\u0438\u043d\u0430\u043d\u0438\u0435 \u0440\u0430\u0441\u0442\u0451\u0442. \u0411\u043e\u043b\u0435\u0435 \u0433\u0440\u043e\u043c\u043a\u0438\u0435 \u0437\u0430\u044f\u0432\u043b\u0435\u043d\u0438\u044f \u0441\u043b\u0430\u0431\u044b. \u041d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u043c\u0435\u0442\u0430\u0430\u043d\u0430\u043b\u0438\u0437\u043e\u0432, \u0432\u043a\u043b\u044e\u0447\u0430\u044f \u0440\u0430\u0431\u043e\u0442\u0443 \u041c\u0435\u043b\u0431\u0438-\u041b\u0435\u0440\u0432\u043e\u0433, \u0420\u0435\u0434\u0438\u043a\u0430 \u0438 \u0425\u0430\u043b\u043c\u0430 (2016), \u043f\u043e\u043a\u0430\u0437\u0430\u043b\u0438, \u0447\u0442\u043e \u0442\u0430\u043a\u0430\u044f \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0430 \u0440\u0430\u0431\u043e\u0447\u0435\u0439 \u043f\u0430\u043c\u044f\u0442\u0438 \u043d\u0435 \u0434\u0430\u0451\u0442 \u043d\u0430\u0434\u0451\u0436\u043d\u043e\u0433\u043e \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0430 \u043d\u0430 \u043e\u0431\u0449\u0438\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0438\u043b\u0438 \u043f\u043e\u0432\u0441\u0435\u0434\u043d\u0435\u0432\u043d\u043e\u0435 \u043c\u044b\u0448\u043b\u0435\u043d\u0438\u0435, \u0430 \u0440\u044f\u0434 \u043d\u0430\u0448\u0443\u043c\u0435\u0432\u0448\u0438\u0445 \u044d\u0444\u0444\u0435\u043a\u0442\u043e\u0432 \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0430 \u043d\u0435 \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u0451\u043b\u0441\u044f. \u0421\u0447\u0438\u0442\u0430\u0439\u0442\u0435 \u044d\u0442\u043e \u043e\u0441\u0442\u0440\u044b\u043c \u0438\u043d\u0441\u0442\u0440\u0443\u043c\u0435\u043d\u0442\u043e\u043c \u0434\u043b\u044f \u043e\u0434\u043d\u043e\u0433\u043e \u043a\u043e\u043d\u043a\u0440\u0435\u0442\u043d\u043e\u0433\u043e \u043d\u0430\u0432\u044b\u043a\u0430, \u0430 \u043d\u0435 \u0441\u043f\u043e\u0441\u043e\u0431\u043e\u043c \u043f\u043e\u0434\u043d\u044f\u0442\u044c IQ.",rec:"\u0421 \u0441\u0430\u043c\u043e\u0433\u043e \u043d\u0430\u0447\u0430\u043b\u0430 \u043e\u0441\u043e\u0437\u043d\u0430\u043d\u043d\u043e \u043f\u043e\u043b\u044c\u0437\u0443\u0439\u0442\u0435\u0441\u044c \u0433\u0440\u0443\u043f\u043f\u0438\u0440\u043e\u0432\u043a\u043e\u0439 \u0438 \u043f\u0440\u043e\u043a\u0430\u0447\u0438\u0432\u0430\u0439\u0442\u0435 \u043d\u0435 \u0442\u043e\u043b\u044c\u043a\u043e \u043f\u0440\u044f\u043c\u043e\u0439, \u043d\u043e \u0438 \u043e\u0431\u0440\u0430\u0442\u043d\u044b\u0439 \u0432\u0430\u0440\u0438\u0430\u043d\u0442: \u0438\u043c\u0435\u043d\u043d\u043e \u0440\u0430\u0437\u0432\u043e\u0440\u043e\u0442 \u043f\u043e\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u0438 \u043d\u0430\u0433\u0440\u0443\u0436\u0430\u0435\u0442 \u0440\u0430\u0431\u043e\u0447\u0443\u044e \u043f\u0430\u043c\u044f\u0442\u044c, \u0430 \u043d\u0435 \u043f\u0440\u043e\u0441\u0442\u043e\u0435 \u0445\u0440\u0430\u043d\u0435\u043d\u0438\u0435.",faq:[["\u0411\u043e\u043b\u044c\u0448\u043e\u0439 \u043e\u0431\u044a\u0451\u043c \u0446\u0438\u0444\u0440 \u043e\u0437\u043d\u0430\u0447\u0430\u0435\u0442, \u0447\u0442\u043e \u0447\u0435\u043b\u043e\u0432\u0435\u043a \u0443\u043c\u043d\u0435\u0435?","\u041e\u0431\u044a\u0451\u043c \u0443\u043c\u0435\u0440\u0435\u043d\u043d\u043e \u0441\u0432\u044f\u0437\u0430\u043d \u0441 \u043f\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044f\u043c\u0438 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442\u0430, \u043d\u043e \u044d\u0442\u043e \u043e\u0434\u043d\u0430 \u0443\u0437\u043a\u0430\u044f \u0441\u043f\u043e\u0441\u043e\u0431\u043d\u043e\u0441\u0442\u044c, \u0430 \u043d\u0435 \u043c\u0435\u0440\u0430 \u0443\u043c\u0430 \u0432 \u0446\u0435\u043b\u043e\u043c. \u041d\u0430\u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u0430\u0432 \u043e\u0431\u044a\u0451\u043c, \u0432\u044b \u043d\u0435 \u043f\u043e\u0432\u044b\u0448\u0430\u0435\u0442\u0435 \u043d\u0430\u0434\u0451\u0436\u043d\u043e \u0441\u0432\u043e\u0439 IQ."],["\u041a\u0430\u043a\u043e\u0439 \u043e\u0431\u044a\u0451\u043c \u0446\u0438\u0444\u0440 \u0441\u0447\u0438\u0442\u0430\u0435\u0442\u0441\u044f \u043d\u043e\u0440\u043c\u043e\u0439?","\u0411\u043e\u043b\u044c\u0448\u0438\u043d\u0441\u0442\u0432\u043e \u0432\u0437\u0440\u043e\u0441\u043b\u044b\u0445 \u043f\u043e\u0432\u0442\u043e\u0440\u044f\u044e\u0442 \u043f\u0440\u0438\u043c\u0435\u0440\u043d\u043e \u0441\u0435\u043c\u044c \u0446\u0438\u0444\u0440 \u0432 \u043f\u0440\u044f\u043c\u043e\u043c \u043f\u043e\u0440\u044f\u0434\u043a\u0435, \u043f\u043b\u044e\u0441-\u043c\u0438\u043d\u0443\u0441 \u0434\u0432\u0435, \u0438 \u043d\u0430 \u043f\u0430\u0440\u0443 \u043c\u0435\u043d\u044c\u0448\u0435 \u0432 \u043e\u0431\u0440\u0430\u0442\u043d\u043e\u043c. \u0412\u0430\u0448 \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u043c\u044b\u0439 \u043f\u043e\u0442\u043e\u043b\u043e\u043a \u043b\u0435\u0436\u0438\u0442 \u043d\u0435\u043c\u043d\u043e\u0433\u043e \u0432\u044b\u0448\u0435 \u0441\u043f\u043e\u043a\u043e\u0439\u043d\u043e\u0433\u043e \u0441\u0440\u0435\u0434\u043d\u0435\u0433\u043e."],["\u0413\u0440\u0443\u043f\u043f\u0438\u0440\u043e\u0432\u043a\u0430 \u2014 \u044d\u0442\u043e \u043d\u0435 \u0436\u0443\u043b\u044c\u043d\u0438\u0447\u0435\u0441\u0442\u0432\u043e?","\u041d\u0435\u0442. \u0413\u0440\u0443\u043f\u043f\u0438\u0440\u043e\u0432\u043a\u0430 \u2014 \u0440\u0435\u0430\u043b\u044c\u043d\u0430\u044f \u0441\u0442\u0440\u0430\u0442\u0435\u0433\u0438\u044f \u043f\u0430\u043c\u044f\u0442\u0438, \u043a\u043e\u0442\u043e\u0440\u0443\u044e \u0437\u0430\u0434\u0430\u043d\u0438\u0435 \u043e\u0442\u0447\u0430\u0441\u0442\u0438 \u0438 \u043f\u0440\u0438\u0437\u0432\u0430\u043d\u043e \u0432\u044b\u044f\u0432\u0438\u0442\u044c, \u0438 \u0438\u043c\u0435\u043d\u043d\u043e \u0442\u0430\u043a \u043e\u043f\u044b\u0442\u043d\u044b\u0435 \u043b\u044e\u0434\u0438 \u0440\u0430\u0441\u0448\u0438\u0440\u044f\u044e\u0442 \u0441\u0432\u043e\u0439 \u043e\u0431\u044a\u0451\u043c. \u0415\u0451 \u0441\u0442\u043e\u0438\u0442 \u043e\u0441\u0432\u043e\u0438\u0442\u044c, \u0430 \u043d\u0435 \u0438\u0437\u0431\u0435\u0433\u0430\u0442\u044c."]],variants:"\u0422\u0438\u043f\u0438\u0447\u043d\u044b\u0435 \u0432\u0430\u0440\u0438\u0430\u0446\u0438\u0438 \u2014 \u043f\u0440\u044f\u043c\u043e\u0439 \u043e\u0431\u044a\u0451\u043c, \u043e\u0431\u0440\u0430\u0442\u043d\u044b\u0439 \u043e\u0431\u044a\u0451\u043c \u0438 \u0443\u043f\u043e\u0440\u044f\u0434\u043e\u0447\u0438\u0432\u0430\u043d\u0438\u0435 (\u043f\u043e\u0432\u0442\u043e\u0440\u0438\u0442\u044c \u0446\u0438\u0444\u0440\u044b \u043f\u043e \u0432\u043e\u0437\u0440\u0430\u0441\u0442\u0430\u043d\u0438\u044e). \u0412 \u0440\u043e\u0434\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0445 \u0437\u0430\u0434\u0430\u043d\u0438\u044f\u0445 \u0446\u0438\u0444\u0440\u044b \u0437\u0430\u043c\u0435\u043d\u044f\u044e\u0442 \u0431\u0443\u043a\u0432\u0430\u043c\u0438, \u0441\u043b\u043e\u0432\u0430\u043c\u0438 \u0438\u043b\u0438 \u043f\u043e\u043b\u043e\u0436\u0435\u043d\u0438\u044f\u043c\u0438 \u0432 \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435, \u043a\u0430\u043a \u0432 \u0442\u0435\u0441\u0442\u0430\u0445 \u043d\u0430 \u043f\u043e\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c \u0431\u0443\u043a\u0432 \u0438 \u0446\u0438\u0444\u0440 \u0438\u043b\u0438 \u0432 \u043c\u0435\u0442\u043e\u0434\u0438\u043a\u0435 \u043f\u043e\u0441\u0442\u0443\u043a\u0438\u0432\u0430\u043d\u0438\u044f \u043f\u043e \u043a\u0443\u0431\u0438\u043a\u0430\u043c \u041a\u043e\u0440\u0441\u0438."},en:{about:"Digit Span shows you a sequence of digits one at a time, then asks you to type them back. In the forward version you reproduce them in the same order; in the backward version you reverse them. The sequence grows by one digit each time you succeed, so the game keeps pushing right up to the edge of how much you can hold.",benefit:"It trains verbal short-term and working memory: how many items you can keep active at once, and, in the backward version, your ability to manipulate that material in your head rather than just store it.",history:"The task comes from early experimental psychology, where measuring the limits of memory was a central question. It was absorbed into the first standardized intelligence batteries in the early 1900s and has stayed in clinical use ever since, which is why almost everyone who has taken a formal IQ or memory assessment has done some form of it.",creator:"The method is credited to British psychologist Joseph Jacobs, who published it in 1887 to measure how much information short-term memory could hold. It was later built into the Binet-Simon scale and then the Wechsler scales (WAIS and WISC), where Digit Span Forward, Backward, and later Sequencing remain standard subtests.",methods:"The core trick is chunking: group a long string into pairs or triples (4 7 1 9 3 8 becomes 47, 19, 38) so you hold three units instead of six. Sub-vocally rehearsing the sequence as it appears and giving it a rhythm both help, and for backward span it is often easier to picture the digits written out and read them off in reverse.",duration:"Short, frequent sessions beat long ones: 5 to 10 minutes a day is plenty, since once the sequence exceeds your span you are mostly accumulating errors, not learning. A few sessions a week is enough to see your reachable length climb over a couple of weeks.",research:"What is solidly shown is narrow: with practice you get better at digit span itself, and your measured span on similar recall tasks rises. The bigger claims are weak. Multiple meta-analyses, including Melby-Lerv\xe5g, Redick and Hulme (2016), found that working memory training of this kind does not produce reliable far transfer to general intelligence or everyday cognition, and several high-profile transfer effects failed to replicate. Treat it as a sharp tool for one specific skill, not an IQ booster.",rec:"Use chunking deliberately from the start, and push backward span as well as forward, since reversing the sequence is the part that exercises working memory rather than plain storage.",faq:[["Is a higher digit span the same as being smarter?","Span correlates modestly with measures of intelligence, but it is one narrow ability, not a measure of overall intelligence. Training your span up does not reliably raise your IQ."],["What is a normal digit span?","Most adults can repeat about seven digits forward, give or take two, and a couple fewer backward. Your trainable ceiling sits a little above your relaxed average."],["Is using chunking cheating?","No. Chunking is a real memory strategy that the task is partly designed to reveal, and it is exactly how skilled performers extend their span. It is worth learning rather than avoiding."]],variants:"Common variations include forward span, backward span, and digit sequencing (recall the digits in numerical order). Related tasks swap digits for letters, words, or spatial positions, as in the letter-number sequencing and Corsi block-tapping tests."},es:{about:"Amplitud de D\xedgitos te muestra una secuencia de cifras de una en una y luego te pide teclearlas de vuelta. En la versi\xf3n directa las reproduces en el mismo orden; en la versi\xf3n inversa las recitas al rev\xe9s. La secuencia crece en una cifra cada vez que aciertas, as\xed que el juego sigue empuj\xe1ndote justo hasta el l\xedmite de lo que puedes retener.",benefit:"Entrena la memoria verbal a corto plazo y la memoria de trabajo: cu\xe1ntos elementos puedes mantener activos a la vez y, en la versi\xf3n inversa, tu capacidad de manipular ese material en la cabeza en lugar de solo almacenarlo.",history:"La tarea proviene de la psicolog\xeda experimental temprana, donde medir los l\xedmites de la memoria era una pregunta central. Se incorpor\xf3 a las primeras bater\xedas estandarizadas de inteligencia a principios del siglo XX y ha seguido en uso cl\xednico desde entonces, por eso casi todo el que ha pasado por una evaluaci\xf3n formal de CI o de memoria ha hecho alguna versi\xf3n de ella.",creator:"El m\xe9todo se atribuye al psic\xf3logo brit\xe1nico Joseph Jacobs, que lo public\xf3 en 1887 para medir cu\xe1nta informaci\xf3n pod\xeda retener la memoria a corto plazo. M\xe1s tarde se integr\xf3 en la escala Binet-Simon y luego en las escalas Wechsler (WAIS y WISC), donde la Amplitud de D\xedgitos directa, inversa y, despu\xe9s, en secuencia siguen siendo subpruebas est\xe1ndar.",methods:"El truco esencial es el agrupamiento: divide una cadena larga en pares o tr\xedos (4 7 1 9 3 8 se convierte en 47, 19, 38) para retener tres unidades en lugar de seis. Repetir la secuencia subvocalmente a medida que aparece y darle un ritmo tambi\xe9n ayudan, y para la amplitud inversa a menudo es m\xe1s f\xe1cil imaginar las cifras escritas y leerlas al rev\xe9s.",duration:"Las sesiones cortas y frecuentes ganan a las largas: de 5 a 10 minutos al d\xeda bastan, ya que una vez que la secuencia supera tu amplitud sobre todo acumulas errores, no aprendizaje. Unas pocas sesiones por semana bastan para ver c\xf3mo tu longitud alcanzable sube a lo largo de un par de semanas.",research:"Lo que est\xe1 s\xf3lidamente demostrado es estrecho: con la pr\xe1ctica mejoras en la propia amplitud de d\xedgitos, y tu amplitud medida en tareas de recuerdo similares aumenta. Las afirmaciones mayores son d\xe9biles. Varios metaan\xe1lisis, incluido el de Melby-Lerv\xe5g, Redick y Hulme (2016), concluyeron que el entrenamiento de la memoria de trabajo de este tipo no produce una transferencia lejana fiable a la inteligencia general ni a la cognici\xf3n cotidiana, y varios efectos de transferencia muy sonados no se replicaron. T\xf3malo como una herramienta afilada para una destreza concreta, no como un potenciador del CI.",rec:"Usa el agrupamiento de forma deliberada desde el principio, y trabaja la amplitud inversa adem\xe1s de la directa, ya que invertir la secuencia es la parte que ejercita la memoria de trabajo y no el simple almacenamiento.",faq:[["\xbfUna amplitud de d\xedgitos mayor es lo mismo que ser m\xe1s inteligente?","La amplitud correlaciona de forma moderada con las medidas de inteligencia, pero es una capacidad estrecha, no una medida de la inteligencia global. Entrenar tu amplitud al alza no eleva de forma fiable tu CI."],["\xbfCu\xe1l es una amplitud de d\xedgitos normal?","La mayor\xeda de los adultos pueden repetir unas siete cifras hacia adelante, m\xe1s o menos dos, y un par menos hacia atr\xe1s. Tu techo entrenable se sit\xfaa un poco por encima de tu promedio relajado."],["\xbfUsar el agrupamiento es hacer trampa?","No. El agrupamiento es una estrategia de memoria real que la tarea est\xe1 en parte dise\xf1ada para revelar, y es exactamente como los expertos extienden su amplitud. Vale la pena aprenderlo en lugar de evitarlo."]],variants:"Las variantes habituales incluyen la amplitud directa, la amplitud inversa y la secuenciaci\xf3n de d\xedgitos (recordar las cifras en orden num\xe9rico). Tareas relacionadas cambian las cifras por letras, palabras o posiciones espaciales, como en las pruebas de secuenciaci\xf3n letra-n\xfamero y de golpeo de bloques de Corsi."},de:{about:"Digit Span zeigt dir eine Folge von Ziffern nacheinander und verlangt dann, sie wieder einzutippen. In der Vorw\xe4rtsvariante gibst du sie in derselben Reihenfolge wieder; in der R\xfcckw\xe4rtsvariante kehrst du sie um. Die Folge w\xe4chst bei jedem Erfolg um eine Ziffer, sodass das Spiel dich immer weiter bis an die Grenze dessen treibt, was du behalten kannst.",benefit:"Es trainiert das verbale Kurzzeit- und Arbeitsged\xe4chtnis: wie viele Elemente du gleichzeitig aktiv halten kannst und \u2013 in der R\xfcckw\xe4rtsvariante \u2013 deine F\xe4higkeit, dieses Material im Kopf zu bearbeiten, statt es nur zu speichern.",history:"Die Aufgabe stammt aus der fr\xfchen experimentellen Psychologie, in der das Messen der Ged\xe4chtnisgrenzen eine zentrale Frage war. Sie wurde Anfang des 20. Jahrhunderts in die ersten standardisierten Intelligenztest-Batterien aufgenommen und ist seither in klinischem Gebrauch geblieben \u2013 deshalb hat fast jeder, der je einen formalen IQ- oder Ged\xe4chtnistest abgelegt hat, eine Form davon durchlaufen.",creator:"Die Methode wird dem britischen Psychologen Joseph Jacobs zugeschrieben, der sie 1887 ver\xf6ffentlichte, um zu messen, wie viel Information das Kurzzeitged\xe4chtnis fassen kann. Sie wurde sp\xe4ter in die Binet-Simon-Skala und dann in die Wechsler-Skalen (WAIS und WISC) eingebaut, wo Zahlenspanne vorw\xe4rts, r\xfcckw\xe4rts und sp\xe4ter als Sequenz weiterhin Standard-Untertests sind.",methods:"Der zentrale Kniff ist das B\xfcndeln: gruppiere eine lange Folge in Paare oder Dreiergruppen (4 7 1 9 3 8 wird zu 47, 19, 38), sodass du drei Einheiten statt sechs beh\xe4ltst. Die Folge beim Erscheinen leise vor sich hin zu sprechen und ihr einen Rhythmus zu geben, hilft beides; bei der R\xfcckw\xe4rtsspanne ist es oft leichter, sich die Ziffern aufgeschrieben vorzustellen und sie r\xfcckw\xe4rts abzulesen.",duration:"Kurze, h\xe4ufige Sitzungen schlagen lange: 5 bis 10 Minuten am Tag reichen v\xf6llig, denn sobald die Folge deine Spanne \xfcbersteigt, sammelst du vor allem Fehler an, statt zu lernen. Ein paar Sitzungen pro Woche gen\xfcgen, um deine erreichbare L\xe4nge im Lauf von zwei Wochen steigen zu sehen.",research:"Solide belegt ist Enges: Mit \xdcbung wirst du besser in der Zahlenspanne selbst, und deine gemessene Spanne in \xe4hnlichen Abrufaufgaben steigt. Die gr\xf6\xdferen Behauptungen sind schwach. Mehrere Meta-Analysen, darunter Melby-Lerv\xe5g, Redick und Hulme (2016), fanden, dass Arbeitsged\xe4chtnistraining dieser Art keinen verl\xe4sslichen Ferntransfer auf die allgemeine Intelligenz oder die allt\xe4gliche Kognition erzeugt, und mehrere viel beachtete Transfereffekte lie\xdfen sich nicht replizieren. Betrachte es als scharfes Werkzeug f\xfcr eine bestimmte Fertigkeit, nicht als IQ-Verst\xe4rker.",rec:"Setze das B\xfcndeln von Anfang an gezielt ein und treibe auch die R\xfcckw\xe4rtsspanne voran, nicht nur die vorw\xe4rts, denn das Umkehren der Folge ist der Teil, der das Arbeitsged\xe4chtnis fordert und nicht blo\xdf das Speichern.",faq:[["Ist eine h\xf6here Zahlenspanne dasselbe wie kl\xfcger zu sein?","Die Spanne korreliert m\xe4\xdfig mit Intelligenzma\xdfen, aber sie ist eine enge Einzelf\xe4higkeit, kein Ma\xdf f\xfcr die Gesamtintelligenz. Seine Spanne hochzutrainieren hebt den IQ nicht verl\xe4sslich."],["Was ist eine normale Zahlenspanne?","Die meisten Erwachsenen k\xf6nnen etwa sieben Ziffern vorw\xe4rts wiederholen, plus/minus zwei, und ein paar weniger r\xfcckw\xe4rts. Deine trainierbare Obergrenze liegt etwas \xfcber deinem entspannten Durchschnitt."],["Ist B\xfcndeln Schummeln?","Nein. B\xfcndeln ist eine echte Ged\xe4chtnisstrategie, die die Aufgabe teils gerade sichtbar machen soll, und genau so erweitern ge\xfcbte K\xf6nner ihre Spanne. Es lohnt sich, es zu lernen statt zu meiden."]],variants:"\xdcbliche Variationen sind die Vorw\xe4rtsspanne, die R\xfcckw\xe4rtsspanne und das Ordnen von Ziffern (die Ziffern in numerischer Reihenfolge abrufen). Verwandte Aufgaben tauschen Ziffern gegen Buchstaben, W\xf6rter oder r\xe4umliche Positionen, wie beim Buchstaben-Zahlen-Folgen-Test und beim Corsi-Block-Tapping-Test."},pt:{about:"Digit Span mostra a voc\xea uma sequ\xeancia de d\xedgitos, um de cada vez, e depois pede que voc\xea os digite de volta. Na vers\xe3o direta, voc\xea os reproduz na mesma ordem; na vers\xe3o inversa, voc\xea os inverte. A sequ\xeancia cresce em um d\xedgito a cada acerto, ent\xe3o o jogo continua empurrando voc\xea at\xe9 o limite do quanto voc\xea consegue segurar.",benefit:"Treina a mem\xf3ria verbal de curto prazo e a de trabalho: quantos itens voc\xea consegue manter ativos ao mesmo tempo e, na vers\xe3o inversa, sua capacidade de manipular esse material na cabe\xe7a, em vez de apenas armazen\xe1-lo.",history:"A tarefa vem dos prim\xf3rdios da psicologia experimental, em que medir os limites da mem\xf3ria era uma quest\xe3o central. Foi incorporada \xe0s primeiras baterias padronizadas de intelig\xeancia no in\xedcio do s\xe9culo XX e permanece em uso cl\xednico desde ent\xe3o, e \xe9 por isso que quase todo mundo que j\xe1 fez uma avalia\xe7\xe3o formal de QI ou de mem\xf3ria passou por alguma forma dela.",creator:"O m\xe9todo \xe9 creditado ao psic\xf3logo brit\xe2nico Joseph Jacobs, que o publicou em 1887 para medir quanta informa\xe7\xe3o a mem\xf3ria de curto prazo conseguia segurar. Mais tarde foi incorporado \xe0 escala Binet-Simon e depois \xe0s escalas Wechsler (WAIS e WISC), onde Digit Span Direto, Inverso e, posteriormente, o de Sequenciamento continuam sendo subtestes padr\xe3o.",methods:"O truque central \xe9 o agrupamento: junte uma sequ\xeancia longa em pares ou trios (4 7 1 9 3 8 vira 47, 19, 38), para voc\xea segurar tr\xeas unidades em vez de seis. Repetir a sequ\xeancia subvocalmente conforme ela aparece e dar a ela um ritmo, ambos ajudam, e, para a vers\xe3o inversa, costuma ser mais f\xe1cil imaginar os d\xedgitos escritos e l\xea-los de tr\xe1s para frente.",duration:"Sess\xf5es curtas e frequentes vencem as longas: 5 a 10 minutos por dia j\xe1 bastam, pois, assim que a sequ\xeancia ultrapassa o seu limite, voc\xea passa a acumular erros em vez de aprender. Algumas sess\xf5es por semana bastam para ver o comprimento que voc\xea alcan\xe7a subir ao longo de algumas semanas.",research:"O que est\xe1 solidamente demonstrado \xe9 restrito: com a pr\xe1tica, voc\xea fica melhor no pr\xf3prio digit span, e o seu limite medido em tarefas de recorda\xe7\xe3o semelhantes sobe. As alega\xe7\xf5es maiores s\xe3o fracas. V\xe1rias meta-an\xe1lises, incluindo a de Melby-Lerv\xe5g, Redick e Hulme (2016), conclu\xedram que esse tipo de treino de mem\xf3ria de trabalho n\xe3o produz transfer\xeancia ampla confi\xe1vel para a intelig\xeancia geral ou a cogni\xe7\xe3o do dia a dia, e v\xe1rios efeitos de transfer\xeancia de grande repercuss\xe3o n\xe3o se replicaram. Encare-o como uma ferramenta afiada para uma habilidade espec\xedfica, e n\xe3o como um turbinador de QI.",rec:"Use o agrupamento de prop\xf3sito desde o in\xedcio e force tamb\xe9m a vers\xe3o inversa, al\xe9m da direta, j\xe1 que inverter a sequ\xeancia \xe9 a parte que exercita a mem\xf3ria de trabalho, e n\xe3o o simples armazenamento.",faq:[["Um digit span maior \xe9 o mesmo que ser mais inteligente?","O limite tem correla\xe7\xe3o modesta com medidas de intelig\xeancia, mas \xe9 uma habilidade restrita, n\xe3o uma medida de intelig\xeancia geral. Treinar o seu limite para cima n\xe3o eleva de forma confi\xe1vel o seu QI."],["Qual \xe9 um digit span normal?","A maioria dos adultos consegue repetir cerca de sete d\xedgitos na ordem direta, mais ou menos dois, e uns dois a menos na ordem inversa. Seu teto trein\xe1vel fica um pouco acima da sua m\xe9dia tranquila."],["Usar o agrupamento \xe9 trapa\xe7a?","N\xe3o. O agrupamento \xe9 uma estrat\xe9gia de mem\xf3ria real que a tarefa, em parte, foi feita para revelar, e \xe9 exatamente assim que pessoas habilidosas ampliam o pr\xf3prio limite. Vale a pena aprend\xea-lo, em vez de evit\xe1-lo."]],variants:"As varia\xe7\xf5es comuns incluem a vers\xe3o direta, a inversa e o sequenciamento de d\xedgitos (recordar os d\xedgitos em ordem num\xe9rica). Tarefas relacionadas trocam os d\xedgitos por letras, palavras ou posi\xe7\xf5es espaciais, como nos testes de sequenciamento de letras e n\xfameros e de toque de blocos de Corsi."},hi:{about:"\u0921\u093f\u091c\u093f\u091f \u0938\u094d\u092a\u0948\u0928 \u0906\u092a\u0915\u094b \u090f\u0915-\u090f\u0915 \u0915\u0930\u0915\u0947 \u0905\u0902\u0915\u094b\u0902 \u0915\u093e \u090f\u0915 \u0915\u094d\u0930\u092e \u0926\u093f\u0916\u093e\u0924\u093e \u0939\u0948, \u092b\u093f\u0930 \u0909\u0928\u094d\u0939\u0947\u0902 \u091f\u093e\u0907\u092a \u0915\u0930\u0915\u0947 \u0935\u093e\u092a\u0938 \u092e\u093e\u0901\u0917\u0924\u093e \u0939\u0948\u0964 \u0906\u0917\u0947 (forward) \u0935\u093e\u0932\u0947 \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u092e\u0947\u0902 \u0906\u092a \u0909\u0928\u094d\u0939\u0947\u0902 \u0909\u0938\u0940 \u0915\u094d\u0930\u092e \u092e\u0947\u0902 \u0926\u094b\u0939\u0930\u093e\u0924\u0947 \u0939\u0948\u0902; \u0909\u0932\u094d\u091f\u0947 (backward) \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u092e\u0947\u0902 \u0909\u0932\u094d\u091f\u0947 \u0915\u094d\u0930\u092e \u092e\u0947\u0902\u0964 \u0939\u0930 \u0938\u092b\u0932 \u092a\u094d\u0930\u092f\u093e\u0938 \u0915\u0947 \u092c\u093e\u0926 \u0915\u094d\u0930\u092e \u092e\u0947\u0902 \u090f\u0915 \u0905\u0902\u0915 \u0914\u0930 \u091c\u0941\u0921\u093c \u091c\u093e\u0924\u093e \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0916\u0947\u0932 \u0906\u092a\u0915\u094b \u0920\u0940\u0915 \u0909\u0938 \u0915\u093f\u0928\u093e\u0930\u0947 \u0924\u0915 \u0927\u0915\u0947\u0932\u0924\u093e \u0930\u0939\u0924\u093e \u0939\u0948 \u091c\u0939\u093e\u0901 \u0924\u0915 \u0906\u092a \u092f\u093e\u0926 \u0930\u0916 \u0938\u0915\u0924\u0947 \u0939\u0948\u0902\u0964",benefit:"\u092f\u0939 \u092e\u094c\u0916\u093f\u0915 \u0905\u0932\u094d\u092a\u0915\u093e\u0932\u093f\u0915 \u0914\u0930 \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932 \u0938\u094d\u092e\u0943\u0924\u093f \u0915\u094b \u0938\u093e\u0927\u0924\u093e \u0939\u0948: \u090f\u0915 \u0938\u093e\u0925 \u0915\u093f\u0924\u0928\u0940 \u091a\u0940\u091c\u093c\u0947\u0902 \u0906\u092a \u0938\u0915\u094d\u0930\u093f\u092f \u0930\u0916 \u0938\u0915\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u0909\u0932\u094d\u091f\u0947 \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u092e\u0947\u0902, \u0909\u0938 \u0938\u093e\u092e\u0917\u094d\u0930\u0940 \u0915\u094b \u0915\u0947\u0935\u0932 \u092d\u0902\u0921\u093e\u0930 \u0915\u0930\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u092e\u0928-\u0939\u0940-\u092e\u0928 \u0909\u0932\u091f-\u092a\u0932\u091f \u0915\u0930 \u092a\u093e\u0928\u0947 \u0915\u0940 \u0915\u094d\u0937\u092e\u0924\u093e\u0964",history:"\u092f\u0939 \u0915\u093e\u0930\u094d\u092f \u0906\u0930\u0902\u092d\u093f\u0915 \u092a\u094d\u0930\u093e\u092f\u094b\u0917\u093f\u0915 \u092e\u0928\u094b\u0935\u093f\u091c\u094d\u091e\u093e\u0928 \u0938\u0947 \u0906\u0924\u093e \u0939\u0948, \u091c\u0939\u093e\u0901 \u0938\u094d\u092e\u0943\u0924\u093f \u0915\u0940 \u0938\u0940\u092e\u093e\u0913\u0902 \u0915\u094b \u092e\u093e\u092a\u0928\u093e \u090f\u0915 \u0915\u0947\u0902\u0926\u094d\u0930\u0940\u092f \u0938\u0935\u093e\u0932 \u0925\u093e\u0964 1900 \u0915\u0947 \u0926\u0936\u0915 \u0915\u0947 \u0936\u0941\u0930\u0942 \u092e\u0947\u0902 \u0907\u0938\u0947 \u092a\u0939\u0932\u0940 \u092e\u093e\u0928\u0915\u0940\u0915\u0943\u0924 \u092c\u0941\u0926\u094d\u0927\u093f-\u092a\u0930\u0940\u0915\u094d\u0937\u0923 \u0936\u0943\u0902\u0916\u0932\u093e\u0913\u0902 \u092e\u0947\u0902 \u0936\u093e\u092e\u093f\u0932 \u0915\u0930 \u0932\u093f\u092f\u093e \u0917\u092f\u093e \u0914\u0930 \u0924\u092c \u0938\u0947 \u092f\u0939 \u0928\u0948\u0926\u093e\u0928\u093f\u0915 \u0909\u092a\u092f\u094b\u0917 \u092e\u0947\u0902 \u092c\u0928\u093e \u0930\u0939\u093e \u0939\u0948 \u2014 \u092f\u0939\u0940 \u0935\u091c\u0939 \u0939\u0948 \u0915\u093f \u091c\u093f\u0938\u0928\u0947 \u092d\u0940 \u0915\u094b\u0908 \u0914\u092a\u091a\u093e\u0930\u093f\u0915 IQ \u092f\u093e \u0938\u094d\u092e\u0943\u0924\u093f \u0906\u0915\u0932\u0928 \u0926\u093f\u092f\u093e \u0939\u0948, \u0909\u0938\u0928\u0947 \u0907\u0938\u0915\u093e \u0915\u094b\u0908 \u0928 \u0915\u094b\u0908 \u0930\u0942\u092a \u091c\u093c\u0930\u0942\u0930 \u0915\u093f\u092f\u093e \u0939\u0948\u0964",creator:"\u0907\u0938 \u0935\u093f\u0927\u093f \u0915\u093e \u0936\u094d\u0930\u0947\u092f \u092c\u094d\u0930\u093f\u091f\u093f\u0936 \u092e\u0928\u094b\u0935\u0948\u091c\u094d\u091e\u093e\u0928\u093f\u0915 \u091c\u094b\u0938\u092b\u093c \u091c\u0948\u0915\u092c\u094d\u0938 (Joseph Jacobs) \u0915\u094b \u091c\u093e\u0924\u093e \u0939\u0948, \u091c\u093f\u0928\u094d\u0939\u094b\u0902\u0928\u0947 1887 \u092e\u0947\u0902 \u092f\u0939 \u092e\u093e\u092a\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0907\u0938\u0947 \u092a\u094d\u0930\u0915\u093e\u0936\u093f\u0924 \u0915\u093f\u092f\u093e \u0915\u093f \u0905\u0932\u094d\u092a\u0915\u093e\u0932\u093f\u0915 \u0938\u094d\u092e\u0943\u0924\u093f \u0915\u093f\u0924\u0928\u0940 \u091c\u093e\u0928\u0915\u093e\u0930\u0940 \u0930\u0916 \u0938\u0915\u0924\u0940 \u0939\u0948\u0964 \u092c\u093e\u0926 \u092e\u0947\u0902 \u0907\u0938\u0947 \u092c\u093f\u0928\u0947-\u0938\u093e\u0907\u092e\u0928 \u092a\u0948\u092e\u093e\u0928\u0947 \u0914\u0930 \u092b\u093f\u0930 \u0935\u0947\u0915\u094d\u0938\u0932\u0930 \u092a\u0948\u092e\u093e\u0928\u094b\u0902 (WAIS \u0914\u0930 WISC) \u092e\u0947\u0902 \u0936\u093e\u092e\u093f\u0932 \u0915\u093f\u092f\u093e \u0917\u092f\u093e, \u091c\u0939\u093e\u0901 \u0921\u093f\u091c\u093f\u091f \u0938\u094d\u092a\u0948\u0928 \u092b\u093c\u0949\u0930\u0935\u0930\u094d\u0921, \u092c\u0948\u0915\u0935\u0930\u094d\u0921, \u0914\u0930 \u092c\u093e\u0926 \u092e\u0947\u0902 \u0938\u0940\u0915\u094d\u0935\u0947\u0902\u0938\u093f\u0902\u0917 \u0906\u091c \u092d\u0940 \u092e\u093e\u0928\u0915 \u0909\u092a-\u092a\u0930\u0940\u0915\u094d\u0937\u0923 \u0939\u0948\u0902\u0964",methods:"\u092e\u0942\u0932 \u0924\u0930\u0915\u0940\u092c \u0939\u0948 \u091a\u0902\u0915\u093f\u0902\u0917 (\u0938\u092e\u0942\u0939 \u092c\u0928\u093e\u0928\u093e): \u090f\u0915 \u0932\u0902\u092c\u0940 \u0932\u0921\u093c\u0940 \u0915\u094b \u091c\u094b\u0921\u093c\u094b\u0902 \u092f\u093e \u0924\u093f\u0915\u0921\u093c\u093f\u092f\u094b\u0902 \u092e\u0947\u0902 \u092c\u093e\u0901\u091f \u0932\u0947\u0902 (4 7 1 9 3 8 \u092c\u0928 \u091c\u093e\u0924\u093e \u0939\u0948 47, 19, 38) \u0924\u093e\u0915\u093f \u0906\u092a \u091b\u0939 \u0915\u0947 \u092c\u091c\u093e\u092f \u0924\u0940\u0928 \u0907\u0915\u093e\u0907\u092f\u093e\u0901 \u0930\u0916\u0947\u0902\u0964 \u0905\u0902\u0915\u094b\u0902 \u0915\u0947 \u0938\u093e\u092e\u0928\u0947 \u0906\u0924\u0947 \u0939\u0940 \u0909\u0928\u094d\u0939\u0947\u0902 \u092e\u0928-\u0939\u0940-\u092e\u0928 \u0926\u094b\u0939\u0930\u093e\u0928\u093e \u0914\u0930 \u0909\u0928\u094d\u0939\u0947\u0902 \u090f\u0915 \u0932\u092f \u0926\u0947\u0928\u093e, \u0926\u094b\u0928\u094b\u0902 \u092e\u0926\u0926 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902; \u0914\u0930 \u0909\u0932\u094d\u091f\u0947 \u0938\u094d\u092a\u0948\u0928 \u0915\u0947 \u0932\u093f\u090f \u0905\u0915\u094d\u0938\u0930 \u0905\u0902\u0915\u094b\u0902 \u0915\u094b \u0932\u093f\u0916\u093e \u0939\u0941\u0906 \u0915\u0932\u094d\u092a\u0928\u093e \u0915\u0930\u0915\u0947 \u0909\u0928\u094d\u0939\u0947\u0902 \u0909\u0932\u094d\u091f\u093e \u092a\u0922\u093c \u0932\u0947\u0928\u093e \u0906\u0938\u093e\u0928 \u0939\u094b\u0924\u093e \u0939\u0948\u0964",duration:"\u091b\u094b\u091f\u0947, \u092c\u093e\u0930-\u092c\u093e\u0930 \u0935\u093e\u0932\u0947 \u0938\u0924\u094d\u0930 \u0932\u0902\u092c\u0947 \u0938\u0924\u094d\u0930\u094b\u0902 \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u0939\u0948\u0902: \u0930\u094b\u091c\u093c 5 \u0938\u0947 10 \u092e\u093f\u0928\u091f \u0915\u093e\u092b\u093c\u0940 \u0939\u0948\u0902, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u091c\u0948\u0938\u0947 \u0939\u0940 \u0915\u094d\u0930\u092e \u0906\u092a\u0915\u0947 \u0938\u094d\u092a\u0948\u0928 \u0938\u0947 \u092c\u0921\u093c\u093e \u0939\u094b \u091c\u093e\u0924\u093e \u0939\u0948, \u0906\u092a \u0938\u0940\u0916\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u091c\u093c\u094d\u092f\u093e\u0926\u093e\u0924\u0930 \u0917\u0932\u0924\u093f\u092f\u093e\u0901 \u0939\u0940 \u091c\u092e\u093e \u0915\u0930\u0928\u0947 \u0932\u0917\u0924\u0947 \u0939\u0948\u0902\u0964 \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u0915\u0941\u091b \u0938\u0924\u094d\u0930 \u0907\u0924\u0928\u0947 \u0915\u093e\u092b\u093c\u0940 \u0939\u0948\u0902 \u0915\u093f \u0915\u0941\u091b \u0939\u092b\u093c\u094d\u0924\u094b\u0902 \u092e\u0947\u0902 \u0906\u092a\u0915\u0940 \u092a\u0939\u0941\u0901\u091a \u0915\u0940 \u0932\u0902\u092c\u093e\u0908 \u092c\u0922\u093c\u0924\u0940 \u0926\u093f\u0916\u0947\u0964",research:"\u091c\u094b \u092a\u0915\u094d\u0915\u093e \u0926\u093f\u0916\u093e\u092f\u093e \u0917\u092f\u093e \u0939\u0948 \u0935\u0939 \u0938\u0902\u0915\u0940\u0930\u094d\u0923 \u0939\u0948: \u0905\u092d\u094d\u092f\u093e\u0938 \u0938\u0947 \u0906\u092a \u0921\u093f\u091c\u093f\u091f \u0938\u094d\u092a\u0948\u0928 \u092e\u0947\u0902 \u0939\u0940 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u092e\u093f\u0932\u0924\u0947-\u091c\u0941\u0932\u0924\u0947 \u0938\u094d\u092e\u0930\u0923 \u0915\u093e\u0930\u094d\u092f\u094b\u0902 \u092a\u0930 \u0906\u092a\u0915\u093e \u092e\u093e\u092a\u093e \u0917\u092f\u093e \u0938\u094d\u092a\u0948\u0928 \u092c\u0922\u093c\u0924\u093e \u0939\u0948\u0964 \u092c\u0921\u093c\u0947 \u0926\u093e\u0935\u0947 \u0915\u092e\u091c\u093c\u094b\u0930 \u0939\u0948\u0902\u0964 Melby-Lerv\xe5g, Redick \u0914\u0930 Hulme (2016) \u0938\u092e\u0947\u0924 \u0915\u0908 \u092e\u0947\u091f\u093e-\u0935\u093f\u0936\u094d\u0932\u0947\u0937\u0923\u094b\u0902 \u0928\u0947 \u092a\u093e\u092f\u093e \u0915\u093f \u0907\u0938 \u0924\u0930\u0939 \u0915\u093e \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932-\u0938\u094d\u092e\u0943\u0924\u093f \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u092c\u0941\u0926\u094d\u0927\u093f \u092f\u093e \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0940 \u0938\u094b\u091a \u0924\u0915 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0926\u0942\u0930-\u0939\u0938\u094d\u0924\u093e\u0902\u0924\u0930\u0923 \u0928\u0939\u0940\u0902 \u0926\u0947\u0924\u093e, \u0914\u0930 \u0915\u0908 \u091a\u0930\u094d\u091a\u093f\u0924 \u0939\u0938\u094d\u0924\u093e\u0902\u0924\u0930\u0923-\u092a\u094d\u0930\u092d\u093e\u0935 \u0926\u094b\u092c\u093e\u0930\u093e \u0928\u0939\u0940\u0902 \u0926\u094b\u0939\u0930\u093e\u090f \u091c\u093e \u0938\u0915\u0947\u0964 \u0907\u0938\u0947 \u090f\u0915 \u0916\u093e\u0938 \u0915\u0941\u0936\u0932\u0924\u093e \u0915\u093e \u0927\u093e\u0930\u0926\u093e\u0930 \u0914\u091c\u093c\u093e\u0930 \u092e\u093e\u0928\u0947\u0902, IQ \u092c\u0922\u093c\u093e\u0928\u0947 \u0935\u093e\u0932\u093e \u0928\u0939\u0940\u0902\u0964",rec:"\u0936\u0941\u0930\u0942 \u0938\u0947 \u0939\u0940 \u091c\u093e\u0928-\u092c\u0942\u091d\u0915\u0930 \u091a\u0902\u0915\u093f\u0902\u0917 \u0915\u093e \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0915\u0930\u0947\u0902, \u0914\u0930 \u0906\u0917\u0947 \u0935\u093e\u0932\u0947 \u0938\u094d\u092a\u0948\u0928 \u0915\u0947 \u0938\u093e\u0925-\u0938\u093e\u0925 \u0909\u0932\u094d\u091f\u0947 \u0938\u094d\u092a\u0948\u0928 \u0915\u094b \u092d\u0940 \u0927\u0915\u0947\u0932\u0947\u0902, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u0915\u094d\u0930\u092e \u0915\u094b \u0909\u0932\u094d\u091f\u093e \u0915\u0930\u0928\u093e \u0939\u0940 \u0935\u0939 \u0939\u093f\u0938\u094d\u0938\u093e \u0939\u0948 \u091c\u094b \u0938\u093e\u0926\u0947 \u092d\u0902\u0921\u093e\u0930\u0923 \u0915\u0947 \u092c\u091c\u093e\u092f \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932 \u0938\u094d\u092e\u0943\u0924\u093f \u0915\u093e \u0935\u094d\u092f\u093e\u092f\u093e\u092e \u0915\u0930\u093e\u0924\u093e \u0939\u0948\u0964",faq:[["\u0915\u094d\u092f\u093e \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0921\u093f\u091c\u093f\u091f \u0938\u094d\u092a\u0948\u0928 \u0915\u093e \u092e\u0924\u0932\u092c \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0939\u094b\u0936\u093f\u092f\u093e\u0930 \u0939\u094b\u0928\u093e \u0939\u0948?","\u0938\u094d\u092a\u0948\u0928 \u0915\u093e \u092c\u0941\u0926\u094d\u0927\u093f \u0915\u0947 \u092e\u093e\u092a\u094b\u0902 \u0938\u0947 \u0939\u0932\u094d\u0915\u093e-\u0938\u093e \u0938\u0902\u092c\u0902\u0927 \u0939\u0948, \u092a\u0930 \u092f\u0939 \u090f\u0915 \u0938\u0902\u0915\u0940\u0930\u094d\u0923 \u0915\u094d\u0937\u092e\u0924\u093e \u0939\u0948, \u0938\u092e\u0917\u094d\u0930 \u092c\u0941\u0926\u094d\u0927\u093f \u0915\u093e \u092e\u093e\u092a \u0928\u0939\u0940\u0902\u0964 \u0905\u092a\u0928\u093e \u0938\u094d\u092a\u0948\u0928 \u092c\u0922\u093c\u093e \u0932\u0947\u0928\u0947 \u0938\u0947 \u0906\u092a\u0915\u093e IQ \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0930\u0942\u092a \u0938\u0947 \u0928\u0939\u0940\u0902 \u092c\u0922\u093c\u0924\u093e\u0964"],["\u0938\u093e\u092e\u093e\u0928\u094d\u092f \u0921\u093f\u091c\u093f\u091f \u0938\u094d\u092a\u0948\u0928 \u0915\u093f\u0924\u0928\u093e \u0939\u094b\u0924\u093e \u0939\u0948?","\u091c\u093c\u094d\u092f\u093e\u0926\u093e\u0924\u0930 \u0935\u092f\u0938\u094d\u0915 \u0932\u0917\u092d\u0917 \u0938\u093e\u0924 \u0905\u0902\u0915 \u0906\u0917\u0947 \u0915\u0940 \u0913\u0930 \u0926\u094b\u0939\u0930\u093e \u0938\u0915\u0924\u0947 \u0939\u0948\u0902, \u0907\u0927\u0930-\u0909\u0927\u0930 \u0926\u094b \u0915\u092e-\u091c\u093c\u094d\u092f\u093e\u0926\u093e, \u0914\u0930 \u0909\u0932\u094d\u091f\u0947 \u092e\u0947\u0902 \u0915\u0941\u091b \u0915\u092e\u0964 \u0905\u092d\u094d\u092f\u093e\u0938 \u0938\u0947 \u092a\u0939\u0941\u0901\u091a\u0928\u0947 \u092f\u094b\u0917\u094d\u092f \u0906\u092a\u0915\u0940 \u090a\u092a\u0930\u0940 \u0938\u0940\u092e\u093e \u0906\u092a\u0915\u0947 \u0938\u0939\u091c \u0914\u0938\u0924 \u0938\u0947 \u0925\u094b\u0921\u093c\u0940 \u090a\u092a\u0930 \u092c\u0948\u0920\u0924\u0940 \u0939\u0948\u0964"],["\u0915\u094d\u092f\u093e \u091a\u0902\u0915\u093f\u0902\u0917 \u0915\u093e \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u092c\u0947\u0908\u092e\u093e\u0928\u0940 \u0939\u0948?","\u0928\u0939\u0940\u0902\u0964 \u091a\u0902\u0915\u093f\u0902\u0917 \u090f\u0915 \u0905\u0938\u0932\u0940 \u0938\u094d\u092e\u0943\u0924\u093f-\u0930\u0923\u0928\u0940\u0924\u093f \u0939\u0948 \u091c\u093f\u0938\u0947 \u0909\u091c\u093e\u0917\u0930 \u0915\u0930\u0928\u093e \u0907\u0938 \u0915\u093e\u0930\u094d\u092f \u0915\u093e \u0906\u0902\u0936\u093f\u0915 \u092e\u0915\u0938\u0926 \u0939\u0940 \u0939\u0948, \u0914\u0930 \u0915\u0941\u0936\u0932 \u0932\u094b\u0917 \u0905\u092a\u0928\u093e \u0938\u094d\u092a\u0948\u0928 \u0920\u0940\u0915 \u0907\u0938\u0940 \u0924\u0930\u0939 \u092c\u0922\u093c\u093e\u0924\u0947 \u0939\u0948\u0902\u0964 \u0907\u0938\u0938\u0947 \u092c\u091a\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u0907\u0938\u0947 \u0938\u0940\u0916\u0928\u093e \u092b\u093c\u093e\u092f\u0926\u0947\u092e\u0902\u0926 \u0939\u0948\u0964"]],variants:"\u0906\u092e \u0935\u093f\u0935\u093f\u0927\u0924\u093e\u0913\u0902 \u092e\u0947\u0902 \u092b\u093c\u0949\u0930\u0935\u0930\u094d\u0921 \u0938\u094d\u092a\u0948\u0928, \u092c\u0948\u0915\u0935\u0930\u094d\u0921 \u0938\u094d\u092a\u0948\u0928, \u0914\u0930 \u0921\u093f\u091c\u093f\u091f \u0938\u0940\u0915\u094d\u0935\u0947\u0902\u0938\u093f\u0902\u0917 (\u0905\u0902\u0915\u094b\u0902 \u0915\u094b \u0938\u0902\u0916\u094d\u092f\u093e\u0924\u094d\u092e\u0915 \u0915\u094d\u0930\u092e \u092e\u0947\u0902 \u092f\u093e\u0926 \u0915\u0930\u0928\u093e) \u0936\u093e\u092e\u093f\u0932 \u0939\u0948\u0902\u0964 \u092e\u093f\u0932\u0924\u0947-\u091c\u0941\u0932\u0924\u0947 \u0915\u093e\u0930\u094d\u092f \u0905\u0902\u0915\u094b\u0902 \u0915\u0940 \u091c\u0917\u0939 \u0905\u0915\u094d\u0937\u0930, \u0936\u092c\u094d\u0926 \u092f\u093e \u0938\u094d\u0925\u093e\u0928\u093f\u0915 \u0938\u094d\u0925\u093f\u0924\u093f \u0930\u0916 \u0926\u0947\u0924\u0947 \u0939\u0948\u0902, \u091c\u0948\u0938\u0947 \u0932\u0947\u091f\u0930-\u0928\u0902\u092c\u0930 \u0938\u0940\u0915\u094d\u0935\u0947\u0902\u0938\u093f\u0902\u0917 \u0914\u0930 \u0915\u0949\u0930\u094d\u0938\u0940 \u092c\u094d\u0932\u0949\u0915-\u091f\u0948\u092a\u093f\u0902\u0917 \u092a\u0930\u0940\u0915\u094d\u0937\u0923\u094b\u0902 \u092e\u0947\u0902\u0964"},zh:{about:"\u300a\u6570\u5b57\u5e7f\u5ea6\u300b\u4f1a\u9010\u4e2a\u5411\u4f60\u5c55\u793a\u4e00\u4e32\u6570\u5b57\uff0c\u7136\u540e\u8981\u6c42\u4f60\u628a\u5b83\u4eec\u8f93\u5165\u56de\u6765\u3002\u5728\u6b63\u5e8f\u7248\u672c\u4e2d\uff0c\u4f60\u6309\u76f8\u540c\u7684\u987a\u5e8f\u590d\u73b0\u5b83\u4eec\uff1b\u5728\u5012\u5e8f\u7248\u672c\u4e2d\uff0c\u4f60\u628a\u5b83\u4eec\u53cd\u8fc7\u6765\u3002\u6bcf\u6210\u529f\u4e00\u6b21\uff0c\u5e8f\u5217\u5c31\u589e\u52a0\u4e00\u4f4d\u6570\u5b57\uff0c\u4e8e\u662f\u6e38\u620f\u4f1a\u4e0d\u65ad\u628a\u4f60\u63a8\u5411\u4f60\u6240\u80fd\u8bb0\u4f4f\u7684\u6781\u9650\u8fb9\u7f18\u3002",benefit:"\u5b83\u8bad\u7ec3\u8a00\u8bed\u77ed\u65f6\u8bb0\u5fc6\u548c\u5de5\u4f5c\u8bb0\u5fc6\uff1a\u4f60\u4e00\u6b21\u80fd\u540c\u65f6\u4fdd\u6301\u591a\u5c11\u4e2a\u6761\u76ee\u6d3b\u8dc3\uff1b\u800c\u5728\u5012\u5e8f\u7248\u672c\u4e2d\uff0c\u8fd8\u8bad\u7ec3\u4f60\u5728\u8111\u4e2d\u64cd\u63a7\u8fd9\u4e9b\u6750\u6599\u3001\u800c\u4e0d\u4ec5\u4ec5\u662f\u5b58\u50a8\u5b83\u4eec\u7684\u80fd\u529b\u3002",history:"\u8fd9\u9879\u4efb\u52a1\u6e90\u81ea\u65e9\u671f\u5b9e\u9a8c\u5fc3\u7406\u5b66\uff0c\u5f53\u65f6\u6d4b\u91cf\u8bb0\u5fc6\u7684\u6781\u9650\u662f\u4e00\u4e2a\u6838\u5fc3\u95ee\u9898\u3002\u5b83\u5728 20 \u4e16\u7eaa\u521d\u88ab\u7eb3\u5165\u6700\u65e9\u7684\u6807\u51c6\u5316\u667a\u529b\u6d4b\u9a8c\u7ec4\u5408\uff0c\u6b64\u540e\u4e00\u76f4\u6cbf\u7528\u4e8e\u4e34\u5e8a\uff0c\u8fd9\u4e5f\u662f\u4e3a\u4f55\u51e0\u4e4e\u6bcf\u4e2a\u505a\u8fc7\u6b63\u5f0f\u667a\u5546\u6216\u8bb0\u5fc6\u8bc4\u4f30\u7684\u4eba\uff0c\u90fd\u505a\u8fc7\u67d0\u79cd\u5f62\u5f0f\u7684\u5b83\u3002",creator:"\u8fd9\u4e00\u65b9\u6cd5\u5f52\u529f\u4e8e\u82f1\u56fd\u5fc3\u7406\u5b66\u5bb6\u7ea6\u745f\u592b\xb7\u96c5\u5404\u5e03\u65af\uff08Joseph Jacobs\uff09\uff0c\u4ed6\u4e8e 1887 \u5e74\u53d1\u8868\u5b83\uff0c\u7528\u4ee5\u6d4b\u91cf\u77ed\u65f6\u8bb0\u5fc6\u80fd\u5bb9\u7eb3\u591a\u5c11\u4fe1\u606f\u3002\u540e\u6765\u5b83\u88ab\u7eb3\u5165\u6bd4\u5948-\u897f\u8499\u91cf\u8868\uff0c\u7ee7\u800c\u8fdb\u5165\u97e6\u514b\u65af\u52d2\u91cf\u8868\uff08WAIS \u548c WISC\uff09\uff0c\u5176\u4e2d\u6570\u5b57\u5e7f\u5ea6\u7684\u6b63\u5e8f\u3001\u5012\u5e8f\uff0c\u4ee5\u53ca\u540e\u6765\u7684\u6392\u5e8f\uff0c\u81f3\u4eca\u4ecd\u662f\u6807\u51c6\u5206\u6d4b\u9a8c\u3002",methods:"\u6838\u5fc3\u7a8d\u95e8\u662f\u7ec4\u5757\uff1a\u628a\u4e00\u957f\u4e32\u5206\u6210\u4e24\u4f4d\u6216\u4e09\u4f4d\u4e00\u7ec4\uff084 7 1 9 3 8 \u53d8\u6210 47\u300119\u300138\uff09\uff0c\u4e8e\u662f\u4f60\u4fdd\u6301\u7684\u662f\u4e09\u4e2a\u5355\u5143\u800c\u975e\u516d\u4e2a\u3002\u5728\u6570\u5b57\u51fa\u73b0\u65f6\u4f4e\u58f0\u9ed8\u5ff5\u8fd9\u4e00\u5e8f\u5217\u3001\u5e76\u8d4b\u4e88\u5b83\u4e00\u79cd\u8282\u594f\uff0c\u4e8c\u8005\u90fd\u6709\u5e2e\u52a9\uff1b\u81f3\u4e8e\u5012\u5e8f\u5e7f\u5ea6\uff0c\u628a\u6570\u5b57\u60f3\u8c61\u6210\u5199\u51fa\u6765\u7684\u6837\u5b50\u3001\u518d\u5012\u7740\u8bfb\u51fa\u6765\uff0c\u5f80\u5f80\u66f4\u5bb9\u6613\u3002",duration:"\u77ed\u800c\u9891\u7e41\u7684\u7ec3\u4e60\u80dc\u8fc7\u5197\u957f\u7684\u7ec3\u4e60\uff1a\u6bcf\u5929 5 \u5230 10 \u5206\u949f\u5c31\u8db3\u591f\uff0c\u56e0\u4e3a\u4e00\u65e6\u5e8f\u5217\u8d85\u8fc7\u4f60\u7684\u5e7f\u5ea6\uff0c\u4f60\u5927\u591a\u662f\u5728\u7d2f\u79ef\u9519\u8bef\uff0c\u800c\u975e\u5728\u5b66\u4e60\u3002\u6bcf\u5468\u51e0\u6b21\uff0c\u5c31\u8db3\u4ee5\u5728\u4e00\u4e24\u5468\u5185\u770b\u5230\u4f60\u80fd\u591f\u8fbe\u5230\u7684\u957f\u5ea6\u6500\u5347\u3002",research:"\u5f97\u5230\u624e\u5b9e\u8bc1\u660e\u7684\u8303\u56f4\u5f88\u7a84\uff1a\u7ecf\u8fc7\u7ec3\u4e60\uff0c\u4f60\u4f1a\u66f4\u64c5\u957f\u6570\u5b57\u5e7f\u5ea6\u672c\u8eab\uff0c\u4f60\u5728\u7c7b\u4f3c\u56de\u5fc6\u4efb\u52a1\u4e0a\u6d4b\u5f97\u7684\u5e7f\u5ea6\u4e5f\u4f1a\u63d0\u9ad8\u3002\u66f4\u5927\u7684\u8bba\u65ad\u5219\u5f88\u8584\u5f31\u3002\u5305\u62ec Melby-Lerv\xe5g\u3001Redick \u548c Hulme\uff082016\uff09\u5728\u5185\u7684\u591a\u9879\u5143\u5206\u6790\u53d1\u73b0\uff0c\u8fd9\u7c7b\u5de5\u4f5c\u8bb0\u5fc6\u8bad\u7ec3\u5e76\u4e0d\u4f1a\u4ea7\u751f\u53ef\u9760\u7684\u3001\u5411\u6574\u4f53\u667a\u529b\u6216\u65e5\u5e38\u8ba4\u77e5\u7684\u8fdc\u8fc1\u79fb\uff0c\u800c\u82e5\u5e72\u5f15\u4eba\u6ce8\u76ee\u7684\u8fc1\u79fb\u6548\u5e94\u4e5f\u672a\u80fd\u91cd\u590d\u51fa\u6765\u3002\u628a\u5b83\u5f53\u4f5c\u78e8\u783a\u67d0\u4e00\u7279\u5b9a\u6280\u80fd\u7684\u5229\u5668\uff0c\u800c\u975e\u667a\u5546\u52a9\u63a8\u5668\u3002",rec:"\u4ece\u4e00\u5f00\u59cb\u5c31\u523b\u610f\u8fd0\u7528\u7ec4\u5757\uff0c\u5e76\u4e14\u8981\u628a\u5012\u5e8f\u5e7f\u5ea6\u548c\u6b63\u5e8f\u4e00\u8d77\u5f80\u4e0a\u63a8\uff0c\u56e0\u4e3a\u53cd\u8f6c\u5e8f\u5217\u624d\u662f\u771f\u6b63\u953b\u70bc\u5de5\u4f5c\u8bb0\u5fc6\u3001\u800c\u975e\u5355\u7eaf\u5b58\u50a8\u7684\u90a3\u90e8\u5206\u3002",faq:[["\u6570\u5b57\u5e7f\u5ea6\u66f4\u9ad8\u662f\u4e0d\u662f\u5c31\u7b49\u4e8e\u66f4\u806a\u660e\uff1f","\u5e7f\u5ea6\u4e0e\u667a\u529b\u6d4b\u91cf\u6709\u4e2d\u7b49\u7a0b\u5ea6\u7684\u76f8\u5173\uff0c\u4f46\u5b83\u662f\u4e00\u9879\u72ed\u7a84\u7684\u80fd\u529b\uff0c\u800c\u975e\u6574\u4f53\u667a\u529b\u7684\u91cf\u5ea6\u3002\u628a\u4f60\u7684\u5e7f\u5ea6\u8bad\u7ec3\u4e0a\u53bb\uff0c\u5e76\u4e0d\u80fd\u53ef\u9760\u5730\u63d0\u5347\u4f60\u7684\u667a\u5546\u3002"],["\u6b63\u5e38\u7684\u6570\u5b57\u5e7f\u5ea6\u662f\u591a\u5c11\uff1f","\u591a\u6570\u6210\u5e74\u4eba\u6b63\u5e8f\u5927\u7ea6\u80fd\u590d\u8ff0\u4e03\u4f4d\u6570\u5b57\uff0c\u4e0a\u4e0b\u6d6e\u52a8\u4e24\u4f4d\uff0c\u5012\u5e8f\u5219\u5c11\u4e24\u4f4d\u5de6\u53f3\u3002\u4f60\u53ef\u8bad\u7ec3\u8fbe\u5230\u7684\u4e0a\u9650\uff0c\u6bd4\u4f60\u653e\u677e\u72b6\u6001\u4e0b\u7684\u5e73\u5747\u503c\u7565\u9ad8\u4e00\u4e9b\u3002"],["\u7528\u7ec4\u5757\u7b97\u4e0d\u7b97\u4f5c\u5f0a\uff1f","\u4e0d\u7b97\u3002\u7ec4\u5757\u662f\u4e00\u79cd\u771f\u5b9e\u7684\u8bb0\u5fc6\u7b56\u7565\uff0c\u8fd9\u9879\u4efb\u52a1\u6709\u4e00\u90e8\u5206\u6b63\u662f\u4e3a\u4e86\u63ed\u793a\u5b83\u800c\u8bbe\u8ba1\u7684\uff0c\u800c\u8fd9\u4e5f\u6b63\u662f\u719f\u7ec3\u8005\u6269\u5c55\u81ea\u5df1\u5e7f\u5ea6\u7684\u65b9\u5f0f\u3002\u5b83\u503c\u5f97\u53bb\u5b66\uff0c\u800c\u4e0d\u662f\u53bb\u56de\u907f\u3002"]],variants:"\u5e38\u89c1\u7684\u53d8\u4f53\u5305\u62ec\u6b63\u5e8f\u5e7f\u5ea6\u3001\u5012\u5e8f\u5e7f\u5ea6\u548c\u6570\u5b57\u6392\u5e8f\uff08\u6309\u6570\u503c\u5927\u5c0f\u56de\u5fc6\u6570\u5b57\uff09\u3002\u76f8\u5173\u4efb\u52a1\u4f1a\u628a\u6570\u5b57\u6362\u6210\u5b57\u6bcd\u3001\u8bcd\u8bed\u6216\u7a7a\u95f4\u4f4d\u7f6e\uff0c\u4f8b\u5982\u5b57\u6bcd-\u6570\u5b57\u6392\u5e8f\u6d4b\u9a8c\u548c\u79d1\u897f\u65b9\u5757\u6572\u51fb\u6d4b\u9a8c\u3002"}},"find-differences":{ru:{about:"\u0412 \xab\u041d\u0430\u0439\u0434\u0438 \u043e\u0442\u043b\u0438\u0447\u0438\u044f\xbb \u043f\u0435\u0440\u0435\u0434 \u0432\u0430\u043c\u0438 \u0434\u0432\u0435 \u043f\u043e\u0447\u0442\u0438 \u043e\u0434\u0438\u043d\u0430\u043a\u043e\u0432\u044b\u0435 \u043a\u0430\u0440\u0442\u0438\u043d\u043a\u0438, \u0438 \u043d\u0443\u0436\u043d\u043e \u043d\u0430\u0439\u0442\u0438 \u0432\u0441\u0435 \u043c\u0435\u043b\u043a\u0438\u0435 \u0440\u0430\u0441\u0445\u043e\u0436\u0434\u0435\u043d\u0438\u044f \u043c\u0435\u0436\u0434\u0443 \u043d\u0438\u043c\u0438, \u043e\u0442\u043c\u0435\u0447\u0430\u044f \u043a\u0430\u0436\u0434\u043e\u0435 \u043a\u0430\u0441\u0430\u043d\u0438\u0435\u043c. \u0420\u0430\u0437\u043b\u0438\u0447\u0438\u044f \u043d\u0430\u043c\u0435\u0440\u0435\u043d\u043d\u043e \u043d\u0435\u0431\u0440\u043e\u0441\u043a\u0438\u0435: \u043f\u0440\u043e\u043f\u0430\u0432\u0448\u0430\u044f \u043f\u0443\u0433\u043e\u0432\u0438\u0446\u0430, \u043f\u0435\u0440\u0435\u043a\u0440\u0430\u0448\u0435\u043d\u043d\u044b\u0439 \u043f\u0440\u0435\u0434\u043c\u0435\u0442, \u043b\u0438\u0448\u043d\u0438\u0439 \u043b\u0438\u0441\u0442\u043e\u043a, \u0447\u0443\u0442\u044c \u0441\u0434\u0432\u0438\u043d\u0443\u0442\u0430\u044f \u0434\u0435\u0442\u0430\u043b\u044c.",benefit:"\u0423\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u0435 \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u0441\u043e\u0441\u0440\u0435\u0434\u043e\u0442\u043e\u0447\u0435\u043d\u043d\u043e\u0435 \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u0435 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u0438 \u0441\u0438\u0441\u0442\u0435\u043c\u043d\u044b\u0439 \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0439 \u043f\u043e\u0438\u0441\u043a, \u0443\u043c\u0435\u043d\u0438\u0435 \u0441\u0440\u0430\u0432\u043d\u0438\u0432\u0430\u0442\u044c \u0434\u0432\u0435 \u0441\u0446\u0435\u043d\u044b \u0434\u0435\u0442\u0430\u043b\u044c \u0437\u0430 \u0434\u0435\u0442\u0430\u043b\u044c\u044e \u0438 \u0437\u0430\u043c\u0435\u0447\u0430\u0442\u044c \u0442\u043e, \u0447\u0442\u043e \u0433\u043b\u0430\u0437 \u043e\u0431\u044b\u0447\u043d\u043e \u043f\u0440\u043e\u0441\u043a\u0430\u043a\u0438\u0432\u0430\u0435\u0442. \u041f\u043e\u0434\u043a\u043b\u044e\u0447\u0430\u0435\u0442\u0441\u044f \u0438 \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u0430\u044f \u0440\u0430\u0431\u043e\u0447\u0430\u044f \u043f\u0430\u043c\u044f\u0442\u044c: \u0432\u044b \u043d\u0430 \u043c\u0438\u0433 \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0435\u0442\u0435 \u043e\u0434\u043d\u0443 \u043a\u0430\u0440\u0442\u0438\u043d\u043a\u0443 \u0432 \u0443\u043c\u0435, \u0440\u0430\u0437\u0433\u043b\u044f\u0434\u044b\u0432\u0430\u044f \u0434\u0440\u0443\u0433\u0443\u044e.",history:"\xab\u041d\u0430\u0439\u0434\u0438 \u043e\u0442\u043b\u0438\u0447\u0438\u044f\xbb \u0432\u044b\u0440\u043e\u0441\u043b\u0438 \u0438\u0437 \u043f\u0435\u0447\u0430\u0442\u043d\u043e\u0439 \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u0438 \u0433\u043e\u043b\u043e\u0432\u043e\u043b\u043e\u043c\u043e\u043a \u0438 \u043a\u043e\u043c\u0438\u043a\u0441\u043e\u0432 XX \u0432\u0435\u043a\u0430, \u043f\u043e\u044f\u0432\u043b\u044f\u044f\u0441\u044c \u0432 \u0434\u0435\u0442\u0441\u043a\u0438\u0445 \u043a\u043d\u0438\u0436\u043a\u0430\u0445 \u0441 \u0437\u0430\u0434\u0430\u043d\u0438\u044f\u043c\u0438, \u043d\u0430 \u0441\u0442\u0440\u0430\u043d\u0438\u0446\u0430\u0445 \u0441 \u043a\u0440\u043e\u0441\u0441\u0432\u043e\u0440\u0434\u0430\u043c\u0438 \u0432 \u0433\u0430\u0437\u0435\u0442\u0430\u0445 \u0438 \u043d\u0430 \u043f\u043e\u0441\u043b\u0435\u0434\u043d\u0438\u0445 \u043f\u043e\u043b\u043e\u0441\u0430\u0445 \u0436\u0443\u0440\u043d\u0430\u043b\u043e\u0432. \u0417\u0430\u0431\u0430\u0432\u0430 \u0440\u0430\u0437\u043e\u0448\u043b\u0430\u0441\u044c \u043f\u043e \u0432\u0441\u0435\u043c\u0443 \u043c\u0438\u0440\u0443 \u043a\u0430\u043a \u0434\u0435\u0448\u0451\u0432\u043e\u0435 \u0440\u0430\u0437\u0432\u043b\u0435\u0447\u0435\u043d\u0438\u0435, \u043d\u0435 \u0442\u0440\u0435\u0431\u0443\u044e\u0449\u0435\u0435 \u0437\u043d\u0430\u043d\u0438\u044f \u044f\u0437\u044b\u043a\u0430, \u0430 \u043f\u043e\u0437\u0436\u0435 \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043d\u043d\u043e \u043f\u0435\u0440\u0435\u0431\u0440\u0430\u043b\u0430\u0441\u044c \u043d\u0430 \u043a\u043e\u043c\u043f\u044c\u044e\u0442\u0435\u0440\u044b, \u0442\u0435\u043b\u0435\u0444\u043e\u043d\u044b \u0438 \u0438\u0433\u0440\u043e\u0432\u044b\u0435 \u0441\u0430\u0439\u0442\u044b.",creator:"\u0423 \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u044f \u043d\u0435\u0442 \u0435\u0434\u0438\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0433\u043e \u0430\u0432\u0442\u043e\u0440\u0430. \u042d\u0442\u043e \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u043e\u043d\u043d\u044b\u0439 \u0436\u0430\u043d\u0440 \u043a\u043d\u0438\u0436\u0435\u043a-\u0433\u043e\u043b\u043e\u0432\u043e\u043b\u043e\u043c\u043e\u043a \u0438 \u0433\u0430\u0437\u0435\u0442\u043d\u044b\u0445 \u0441\u0442\u0440\u0430\u043d\u0438\u0446, \u043e\u0442\u0442\u043e\u0447\u0435\u043d\u043d\u044b\u0439 \u043c\u043d\u043e\u0436\u0435\u0441\u0442\u0432\u043e\u043c \u0445\u0443\u0434\u043e\u0436\u043d\u0438\u043a\u043e\u0432 \u0438 \u0441\u043e\u0441\u0442\u0430\u0432\u0438\u0442\u0435\u043b\u0435\u0439, \u0430 \u043d\u0435 \u043f\u0440\u0438\u043f\u0438\u0441\u0430\u043d\u043d\u044b\u0439 \u043e\u0434\u043d\u043e\u043c\u0443 \u0447\u0435\u043b\u043e\u0432\u0435\u043a\u0443 \u0438\u043b\u0438 \u043a\u043e\u043d\u043a\u0440\u0435\u0442\u043d\u043e\u043c\u0443 \u0433\u043e\u0434\u0443, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u043a \u043b\u044e\u0431\u044b\u043c \u0441\u0441\u044b\u043b\u043a\u0430\u043c \u043d\u0430 \xab\u0438\u0437\u043e\u0431\u0440\u0435\u0442\u0430\u0442\u0435\u043b\u044f\xbb \u0441\u0442\u043e\u0438\u0442 \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u044c\u0441\u044f \u0441 \u043d\u0435\u0434\u043e\u0432\u0435\u0440\u0438\u0435\u043c.",methods:"\u0414\u0432\u0438\u0433\u0430\u0439\u0442\u0435\u0441\u044c \u0432 \u0437\u0430\u0434\u0430\u043d\u043d\u043e\u043c \u043f\u043e\u0440\u044f\u0434\u043a\u0435, \u0430 \u043d\u0435 \u043c\u0435\u0447\u0438\u0442\u0435\u0441\u044c \u043f\u043e \u043a\u0430\u0440\u0442\u0438\u043d\u043a\u0435: \u0441\u043b\u0435\u0432\u0430 \u043d\u0430\u043f\u0440\u0430\u0432\u043e, \u0441\u0432\u0435\u0440\u0445\u0443 \u0432\u043d\u0438\u0437 \u0438\u043b\u0438 \u0440\u0430\u0437\u0431\u0435\u0439\u0442\u0435 \u0438\u0437\u043e\u0431\u0440\u0430\u0436\u0435\u043d\u0438\u0435 \u043d\u0430 \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u0438 \u0438 \u0437\u0430\u043a\u0440\u044b\u0432\u0430\u0439\u0442\u0435 \u043f\u043e \u043e\u0434\u043d\u043e\u0439. \u0421\u0440\u0430\u0432\u043d\u0438\u0432\u0430\u0439\u0442\u0435 \u043e\u0434\u043d\u0438 \u0438 \u0442\u0435 \u0436\u0435 \u0443\u0447\u0430\u0441\u0442\u043a\u0438 \u0434\u0432\u0443\u0445 \u043a\u0430\u0440\u0442\u0438\u043d\u043e\u043a \u043d\u0430\u043f\u0440\u044f\u043c\u0443\u044e \u0438 \u043e\u0441\u043e\u0431\u0435\u043d\u043d\u043e \u0432\u043d\u0438\u043c\u0430\u0442\u0435\u043b\u044c\u043d\u043e \u0441\u043c\u043e\u0442\u0440\u0438\u0442\u0435 \u043d\u0430 \u043a\u0440\u0430\u044f, \u0444\u043e\u043d \u0438 \u043f\u043e\u0432\u0442\u043e\u0440\u044f\u044e\u0449\u0438\u0435\u0441\u044f \u0443\u0437\u043e\u0440\u044b, \u0433\u0434\u0435 \u0440\u0430\u0437\u043b\u0438\u0447\u0438\u044f \u043f\u0440\u044f\u0447\u0443\u0442\u0441\u044f \u043b\u0443\u0447\u0448\u0435 \u0432\u0441\u0435\u0433\u043e. \u0418\u0437\u0432\u0435\u0441\u0442\u043d\u044b\u0439 \u043f\u0440\u0438\u0451\u043c \u0434\u043b\u044f \u0441\u0442\u0430\u0442\u0438\u0447\u043d\u044b\u0445 \u043f\u0435\u0447\u0430\u0442\u043d\u044b\u0445 \u043f\u0430\u0440: \u0440\u0430\u0441\u0441\u043b\u0430\u0431\u0438\u0442\u044c \u0432\u0437\u0433\u043b\u044f\u0434 \u0442\u0430\u043a, \u0447\u0442\u043e\u0431\u044b \u043a\u0430\u0440\u0442\u0438\u043d\u043a\u0438 \u043d\u0430\u043b\u043e\u0436\u0438\u043b\u0438\u0441\u044c, \u0438 \u0442\u043e\u0433\u0434\u0430 \u043e\u0442\u043b\u0438\u0447\u0438\u0435 \u043a\u0430\u043a \u0431\u0443\u0434\u0442\u043e \u043c\u0438\u0433\u0430\u0435\u0442.",duration:"\u041b\u0443\u0447\u0448\u0435 \u0432\u0441\u0435\u0433\u043e \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u0435 \u043f\u043e\u0434\u0445\u043e\u0434\u044b: \u0434\u0435\u0441\u044f\u0442\u044c-\u043f\u044f\u0442\u043d\u0430\u0434\u0446\u0430\u0442\u044c \u043c\u0438\u043d\u0443\u0442 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0440\u0430\u0437 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e \u0432\u043f\u043e\u043b\u043d\u0435 \u0434\u043e\u0441\u0442\u0430\u0442\u043e\u0447\u043d\u043e. \u041a\u0430\u043a \u0438 \u0432 \u0431\u043e\u043b\u044c\u0448\u0438\u043d\u0441\u0442\u0432\u0435 \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0445 \u0433\u043e\u043b\u043e\u0432\u043e\u043b\u043e\u043c\u043e\u043a, \u043a\u0430\u0447\u0435\u0441\u0442\u0432\u043e \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f \u0432\u0430\u0436\u043d\u0435\u0435 \u043c\u043d\u043e\u0433\u043e\u0447\u0430\u0441\u043e\u0432\u043e\u0439 \u0437\u0443\u0431\u0440\u0451\u0436\u043a\u0438, \u0430 \u0443\u0441\u0442\u0430\u043b\u044b\u0439 \u043d\u0435\u0432\u043d\u0438\u043c\u0430\u0442\u0435\u043b\u044c\u043d\u044b\u0439 \u043f\u0440\u043e\u0441\u043c\u043e\u0442\u0440 \u043f\u043e\u0447\u0442\u0438 \u043d\u0438\u0447\u0435\u043c\u0443 \u043d\u0435 \u0443\u0447\u0438\u0442.",research:"\u0414\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432\u0430 \u043a\u0440\u0435\u043f\u0447\u0435 \u0432\u0441\u0435\u0433\u043e \u0440\u043e\u0432\u043d\u043e \u0434\u043b\u044f \u043e\u0436\u0438\u0434\u0430\u0435\u043c\u043e\u0433\u043e: \u0432\u044b \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u0438 \u0442\u043e\u0447\u043d\u0435\u0435 \u043d\u0430\u0445\u043e\u0434\u0438\u0442\u0435 \u043e\u0442\u043b\u0438\u0447\u0438\u044f, \u0438 \u0435\u0441\u0442\u044c \u043d\u0435\u0431\u043e\u043b\u044c\u0448\u043e\u0439 \u043f\u0435\u0440\u0435\u043d\u043e\u0441 \u043d\u0430 \u0440\u043e\u0434\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0435 \u0437\u0430\u0434\u0430\u0447\u0438 \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u0433\u043e \u043f\u043e\u0438\u0441\u043a\u0430. \u0418\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u044f \u043b\u0435\u0436\u0430\u0449\u0435\u0439 \u0432 \u043e\u0441\u043d\u043e\u0432\u0435 \u043f\u0430\u0440\u0430\u0434\u0438\u0433\u043c\u044b \u043e\u0431\u043d\u0430\u0440\u0443\u0436\u0435\u043d\u0438\u044f \u0438\u0437\u043c\u0435\u043d\u0435\u043d\u0438\u0439 \u043f\u043e\u043a\u0430\u0437\u044b\u0432\u0430\u044e\u0442 \u0432 \u043e\u0441\u043d\u043e\u0432\u043d\u043e\u043c \u0443\u0437\u043a\u0438\u0439, \u043f\u0440\u0438\u0432\u044f\u0437\u0430\u043d\u043d\u044b\u0439 \u043a \u0441\u0430\u043c\u043e\u0439 \u0437\u0430\u0434\u0430\u0447\u0435 \u044d\u0444\u0444\u0435\u043a\u0442 \u0441 \u043b\u0438\u0448\u044c \u0443\u043c\u0435\u0440\u0435\u043d\u043d\u044b\u043c \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u043e\u043c, \u0430 \u043f\u043e\u043f\u0443\u043b\u044f\u0440\u043d\u044b\u0435 \u0438\u0434\u0435\u0438, \u0431\u0443\u0434\u0442\u043e \u044d\u0442\u043e \u043f\u043e\u0434\u043d\u0438\u043c\u0430\u0435\u0442 \u043e\u0431\u0449\u0438\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0438\u043b\u0438 \u0437\u0430\u0449\u0438\u0449\u0430\u0435\u0442 \u043e\u0442 \u0432\u043e\u0437\u0440\u0430\u0441\u0442\u043d\u043e\u0433\u043e \u0441\u043f\u0430\u0434\u0430, \u043d\u0435 \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u044e\u0442\u0441\u044f, \u0442\u0430\u043a \u0447\u0442\u043e \u043a \u0433\u0440\u043e\u043c\u043a\u0438\u043c \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f\u043c \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u0435\u0441\u044c \u043e\u0441\u0442\u043e\u0440\u043e\u0436\u043d\u043e.",rec:"\u0412\u044b\u0431\u0435\u0440\u0438\u0442\u0435 \u043c\u0430\u0440\u0448\u0440\u0443\u0442 \u043e\u0441\u043c\u043e\u0442\u0440\u0430 \u0438 \u0434\u0435\u0440\u0436\u0438\u0442\u0435\u0441\u044c \u0435\u0433\u043e \u043a\u0430\u0436\u0434\u044b\u0439 \u0440\u0430\u0443\u043d\u0434, \u0432\u043c\u0435\u0441\u0442\u043e \u0442\u043e\u0433\u043e \u0447\u0442\u043e\u0431\u044b \u0438\u0441\u043a\u0430\u0442\u044c \u043d\u0430\u0443\u0433\u0430\u0434, \u0438 \u0432\u044b \u0431\u0443\u0434\u0435\u0442\u0435 \u043d\u0430\u0445\u043e\u0434\u0438\u0442\u044c \u043e\u0442\u043b\u0438\u0447\u0438\u044f \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u0438 \u043f\u0440\u043e\u043f\u0443\u0441\u043a\u0430\u0442\u044c \u043c\u0435\u043d\u044c\u0448\u0435.",faq:[["\u0411\u044b\u0441\u0442\u0440\u043e \u043d\u0430\u0445\u043e\u0436\u0443 \u043e\u0442\u043b\u0438\u0447\u0438\u044f \u2014 \u044d\u0442\u043e \u043f\u0440\u0438\u0437\u043d\u0430\u043a \u0432\u044b\u0441\u043e\u043a\u043e\u0433\u043e \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442\u0430?","\u041d\u0435\u0442. \u042d\u0442\u043e \u0432 \u043f\u0435\u0440\u0432\u0443\u044e \u043e\u0447\u0435\u0440\u0435\u0434\u044c \u0433\u043e\u0432\u043e\u0440\u0438\u0442 \u043e \u043d\u0430\u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u043e\u0441\u0442\u0438 \u0438\u043c\u0435\u043d\u043d\u043e \u0432 \u0442\u0430\u043a\u043e\u043c \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u043c \u043f\u043e\u0438\u0441\u043a\u0435: \u043d\u0430\u0432\u044b\u043a, \u0430 \u043d\u0435 \u043c\u0435\u0440\u0438\u043b\u043e \u043e\u0431\u0449\u0435\u0433\u043e \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442\u0430."],["\u0423\u043b\u0443\u0447\u0448\u0438\u0442 \u043b\u0438 \u044d\u0442\u043e \u043c\u043e\u0451 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u0438 \u043f\u0430\u043c\u044f\u0442\u044c \u0432 \u043f\u043e\u0432\u0441\u0435\u0434\u043d\u0435\u0432\u043d\u043e\u0439 \u0436\u0438\u0437\u043d\u0438?","\u0421\u043f\u043e\u0441\u043e\u0431\u043d\u043e\u0441\u0442\u044c \u0437\u0430\u043c\u0435\u0447\u0430\u0442\u044c \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0435 \u0438\u0437\u043c\u0435\u043d\u0435\u043d\u0438\u044f \u0440\u0430\u0441\u0442\u0451\u0442 \u043d\u0430\u0434\u0451\u0436\u043d\u043e, \u043d\u043e \u0448\u0438\u0440\u043e\u043a\u0438\u0439 \u043f\u0435\u0440\u0435\u043d\u043e\u0441 \u043d\u0430 \u0431\u044b\u0442\u043e\u0432\u043e\u0435 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u0438\u043b\u0438 \u043f\u0430\u043c\u044f\u0442\u044c \u0441\u043b\u0430\u0431 \u0438 \u043d\u0435 \u0434\u043e\u043a\u0430\u0437\u0430\u043d, \u0442\u0430\u043a \u0447\u0442\u043e \u0432\u043e\u0441\u043f\u0440\u0438\u043d\u0438\u043c\u0430\u0439\u0442\u0435 \u044d\u0442\u043e \u043a\u0430\u043a \u0445\u043e\u0440\u043e\u0448\u0443\u044e \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0443 \u0432\u043d\u0438\u043c\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0433\u043e \u0432\u0437\u0433\u043b\u044f\u0434\u0430, \u0430 \u043d\u0435 \u043a\u0430\u043a \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043e \u0434\u043b\u044f \u043a\u043e\u043d\u0446\u0435\u043d\u0442\u0440\u0430\u0446\u0438\u0438."],["\u0417\u0430\u0441\u0442\u0440\u044f\u043b \u0438 \u043d\u0435 \u043c\u043e\u0433\u0443 \u043d\u0430\u0439\u0442\u0438 \u043f\u043e\u0441\u043b\u0435\u0434\u043d\u0435\u0435 \u043e\u0442\u043b\u0438\u0447\u0438\u0435. \u0427\u0442\u043e \u043f\u043e\u043c\u043e\u0433\u0430\u0435\u0442?","\u041f\u0435\u0440\u0435\u0441\u0442\u0430\u043d\u044c\u0442\u0435 \u0438\u0441\u043a\u0430\u0442\u044c \u043d\u0430\u0443\u0433\u0430\u0434. \u0417\u0430\u043a\u0440\u043e\u0439\u0442\u0435 \u043e\u0434\u043d\u0443 \u043a\u0430\u0440\u0442\u0438\u043d\u043a\u0443, \u0438\u0437\u0443\u0447\u0438\u0442\u0435 \u0434\u0440\u0443\u0433\u0443\u044e \u043f\u043e \u0443\u0447\u0430\u0441\u0442\u043a\u0430\u043c, \u0437\u0430\u0442\u0435\u043c \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0438\u0442\u0435\u0441\u044c \u0438 \u043f\u0440\u043e\u0432\u0435\u0440\u044c\u0442\u0435 \u043c\u0435\u0441\u0442\u0430, \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u0447\u0430\u0449\u0435 \u0432\u0441\u0435\u0433\u043e \u043f\u0440\u043e\u043f\u0443\u0441\u043a\u0430\u044e\u0442: \u0443\u0433\u043b\u044b, \u0444\u043e\u043d \u0438 \u043f\u043e\u0432\u0442\u043e\u0440\u044f\u044e\u0449\u0438\u0435\u0441\u044f \u0442\u0435\u043a\u0441\u0442\u0443\u0440\u044b."]],variants:"\u0421\u0440\u0435\u0434\u0438 \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u043e\u0432: \u0440\u0430\u0443\u043d\u0434\u044b \u043d\u0430 \u0432\u0440\u0435\u043c\u044f, \u0444\u0438\u043a\u0441\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u043e\u0435 \u0447\u0438\u0441\u043b\u043e \u043e\u0442\u043b\u0438\u0447\u0438\u0439 \u043f\u0440\u043e\u0442\u0438\u0432 \xab\u043d\u0430\u0439\u0442\u0438 \u0432\u0441\u0435\xbb, \u043f\u0430\u0440\u044b \u0444\u043e\u0442\u043e\u0433\u0440\u0430\u0444\u0438\u0439 \u043f\u0440\u043e\u0442\u0438\u0432 \u0440\u0438\u0441\u043e\u0432\u0430\u043d\u043d\u044b\u0445 \u043a\u0430\u0440\u0442\u0438\u043d\u043e\u043a, \u0434\u0432\u0438\u0436\u0443\u0449\u0438\u0435\u0441\u044f \u0438 \u0430\u043d\u0438\u043c\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u044b\u0435 \u0441\u0446\u0435\u043d\u044b, \u043f\u043e\u0438\u0441\u043a \u0441\u043f\u0440\u044f\u0442\u0430\u043d\u043d\u044b\u0445 \u043f\u0440\u0435\u0434\u043c\u0435\u0442\u043e\u0432 \u0438 \u043c\u0430\u0441\u0448\u0442\u0430\u0431\u0438\u0440\u0443\u0435\u043c\u044b\u0435 \u0434\u0435\u0442\u0430\u043b\u044c\u043d\u044b\u0435 \u0438\u0437\u043e\u0431\u0440\u0430\u0436\u0435\u043d\u0438\u044f, \u0432\u043e\u0437\u043d\u0430\u0433\u0440\u0430\u0436\u0434\u0430\u044e\u0449\u0438\u0435 \u0442\u0435\u0440\u043f\u0435\u043b\u0438\u0432\u043e\u0435 \u0441\u0440\u0430\u0432\u043d\u0435\u043d\u0438\u0435."},en:{about:"Find Differences shows you two almost identical pictures side by side, and your job is to spot every small change between them, tapping each difference as you find it. The changes are deliberately subtle: a missing button, a recoloured object, an extra leaf, a shape that moved a little.",benefit:"It trains focused visual attention and systematic visual search, the ability to compare two scenes feature by feature and to notice a change that your eye would otherwise skip over. It also leans on visual working memory, because you briefly hold one image in mind while scanning the other.",history:"Spot the difference grew out of the printed puzzle and comic tradition of the twentieth century, appearing in children's activity books, newspaper puzzle pages, and magazine back pages. It spread worldwide as a cheap, language-free amusement, and later moved naturally onto computers, phones, and casual game sites.",creator:"It has no single inventor. It is a traditional puzzle-book and newspaper genre, refined by countless illustrators and puzzle editors rather than credited to one person or one year, so any claim of a named creator should be treated with suspicion.",methods:"Work in a fixed order instead of darting around: sweep left to right, top to bottom, or split each image into quadrants and clear one at a time. Compare matching regions of the two pictures directly, and pay special attention to edges, backgrounds, and repeated patterns, where changes hide best. A known trick on static printed pairs is to relax your eyes until the two images overlap, so the difference seems to flicker.",duration:"Short sessions work best: ten to fifteen minutes, a few times a week, is plenty. As with most visual puzzles, quality of attention matters far more than grinding for hours, and tired, careless scanning teaches you little.",research:"Evidence is strongest for exactly what you would expect: you get faster and more accurate at finding differences, and there is some carry-over to related visual-search tasks. Studies on the underlying change-detection paradigm report mostly narrow, task-specific gains with only modest transfer, and the popular ideas that it raises general intelligence or wards off cognitive decline are not supported, so treat those grand promises with caution.",rec:"Pick a scanning route and stick to it every round, rather than hunting at random, and you will find the changes faster and miss fewer of them.",faq:[["Is finding differences faster a sign of higher intelligence?","No. It mainly shows you have practised this kind of visual search; it is a trained skill, not a measure of general intelligence."],["Will it improve my everyday attention and memory?","It reliably improves how well you spot visual changes, but broad transfer to everyday attention or memory is weak and unproven, so enjoy it as good practice for careful looking rather than a fix for focus."],["I am stuck and cannot find the last difference. What helps?","Stop scanning randomly. Cover one image, study the other region by region, then switch, and check the spots people overlook most: corners, backgrounds, and repeating textures."]],variants:"Variants include timed rounds, a fixed difference count versus find-them-all, photo pairs versus cartoon illustrations, moving or animated scenes, hidden-object hunts, and zoomable high-detail images that reward patient, careful comparison."},es:{about:"Encuentra las Diferencias te muestra dos im\xe1genes casi id\xe9nticas una al lado de la otra, y tu tarea es detectar cada peque\xf1o cambio entre ellas, tocando cada diferencia a medida que la encuentras. Los cambios son deliberadamente sutiles: un bot\xf3n que falta, un objeto recoloreado, una hoja de m\xe1s, una forma que se movi\xf3 un poco.",benefit:"Entrena la atenci\xf3n visual concentrada y la b\xfasqueda visual sistem\xe1tica, la capacidad de comparar dos escenas rasgo a rasgo y de advertir un cambio que de otro modo tu ojo pasar\xeda por alto. Tambi\xe9n se apoya en la memoria de trabajo visual, porque retienes brevemente una imagen en mente mientras examinas la otra.",history:"Encontrar diferencias surgi\xf3 de la tradici\xf3n de los pasatiempos impresos y los c\xf3mics del siglo XX, apareciendo en libros de actividades infantiles, en las p\xe1ginas de pasatiempos de los peri\xf3dicos y en las contraportadas de las revistas. Se extendi\xf3 por todo el mundo como un entretenimiento barato y sin barreras de idioma, y m\xe1s tarde pas\xf3 con naturalidad a ordenadores, tel\xe9fonos y sitios de juegos casuales.",creator:"No tiene un \xfanico inventor. Es un g\xe9nero tradicional de los libros de pasatiempos y los peri\xf3dicos, pulido por innumerables ilustradores y editores de pasatiempos en vez de atribuirse a una persona o un a\xf1o concretos, as\xed que cualquier afirmaci\xf3n de un creador con nombre deber\xeda tomarse con recelo.",methods:"Trabaja en un orden fijo en lugar de saltar de un lado a otro: barre de izquierda a derecha y de arriba abajo, o divide cada imagen en cuadrantes y despeja uno cada vez. Compara directamente las zonas equivalentes de las dos im\xe1genes, y presta especial atenci\xf3n a los bordes, los fondos y los patrones repetidos, donde mejor se esconden los cambios. Un truco conocido con pares impresos est\xe1ticos es relajar la vista hasta que las dos im\xe1genes se superpongan, de modo que la diferencia parezca parpadear.",duration:"Lo que mejor funciona son las sesiones cortas: de diez a quince minutos, unas pocas veces por semana, basta de sobra. Como en la mayor\xeda de los pasatiempos visuales, la calidad de la atenci\xf3n importa mucho m\xe1s que machacar durante horas, y un rastreo cansado y descuidado ense\xf1a poco.",research:"La evidencia es m\xe1s s\xf3lida justo en lo que cabr\xeda esperar: te vuelves m\xe1s r\xe1pido y m\xe1s preciso encontrando diferencias, y hay cierto traslado a tareas relacionadas de b\xfasqueda visual. Los estudios sobre el paradigma subyacente de detecci\xf3n de cambios informan en su mayor\xeda de mejoras estrechas y espec\xedficas de la tarea, con una transferencia solo modesta, y las ideas populares de que eleva la inteligencia general o protege del deterioro cognitivo no est\xe1n respaldadas, as\xed que toma con cautela esas grandes promesas.",rec:"Elige una ruta de rastreo y mantenla en cada ronda, en lugar de buscar al azar, y encontrar\xe1s los cambios m\xe1s r\xe1pido y se te escapar\xe1n menos.",faq:[["\xbfEncontrar diferencias m\xe1s r\xe1pido es se\xf1al de mayor inteligencia?","No. Sobre todo demuestra que has practicado este tipo de b\xfasqueda visual; es una destreza entrenada, no una medida de la inteligencia general."],["\xbfMejorar\xe1 mi atenci\xf3n y mi memoria en el d\xeda a d\xeda?","De forma fiable mejora lo bien que detectas cambios visuales, pero la transferencia amplia a la atenci\xf3n o la memoria cotidianas es d\xe9bil y no est\xe1 demostrada, as\xed que disfr\xfatalo como buena pr\xe1ctica para mirar con cuidado y no como un remedio para la concentraci\xf3n."],["Estoy atascado y no encuentro la \xfaltima diferencia. \xbfQu\xe9 ayuda?","Deja de rastrear al azar. Tapa una imagen, estudia la otra zona por zona, luego cambia, y revisa los puntos que la gente m\xe1s pasa por alto: las esquinas, los fondos y las texturas que se repiten."]],variants:"Las variantes incluyen rondas con tiempo, un n\xfamero fijo de diferencias frente a encontrarlas todas, pares de fotos frente a ilustraciones de dibujos animados, escenas en movimiento o animadas, b\xfasquedas de objetos ocultos, e im\xe1genes de alto detalle con zoom que recompensan una comparaci\xf3n paciente y cuidadosa."},de:{about:"Find Differences zeigt dir zwei fast identische Bilder nebeneinander, und du musst jede kleine Abweichung zwischen ihnen aufsp\xfcren und antippen, sobald du sie findest. Die \xc4nderungen sind bewusst unauff\xe4llig: ein fehlender Knopf, ein umgef\xe4rbter Gegenstand, ein zus\xe4tzliches Blatt, eine Form, die sich ein wenig verschoben hat.",benefit:"Es trainiert die gezielte visuelle Aufmerksamkeit und das systematische Absuchen \u2013 die F\xe4higkeit, zwei Szenen Merkmal f\xfcr Merkmal zu vergleichen und eine \xc4nderung zu bemerken, die das Auge sonst \xfcberspringen w\xfcrde. Es beansprucht auch das visuelle Arbeitsged\xe4chtnis, weil du ein Bild kurz im Kopf beh\xe4ltst, w\xe4hrend du das andere absuchst.",history:"Das Fehlersuchbild ging aus der gedruckten R\xe4tsel- und Comic-Tradition des 20. Jahrhunderts hervor und erschien in Besch\xe4ftigungsb\xfcchern f\xfcr Kinder, auf R\xe4tselseiten von Zeitungen und auf den hinteren Seiten von Zeitschriften. Es verbreitete sich weltweit als g\xfcnstiger, sprachfreier Zeitvertreib und wanderte sp\xe4ter ganz selbstverst\xe4ndlich auf Computer, Handys und Gelegenheitsspiel-Seiten.",creator:"Es hat keinen einzelnen Erfinder. Es ist ein traditionelles Genre aus R\xe4tselheften und Zeitungen, verfeinert von unz\xe4hligen Illustratoren und R\xe4tselredakteuren, statt einer Person oder einem Jahr zugeschrieben zu sein \u2013 jede Behauptung eines namentlichen Sch\xf6pfers sollte man daher mit Skepsis betrachten.",methods:"Arbeite in einer festen Reihenfolge, statt umherzuspringen: streiche von links nach rechts und von oben nach unten, oder teile jedes Bild in Viertel und arbeite eines nach dem anderen ab. Vergleiche die einander entsprechenden Bereiche der beiden Bilder direkt und achte besonders auf R\xe4nder, Hintergr\xfcnde und wiederkehrende Muster, wo sich \xc4nderungen am besten verstecken. Ein bekannter Trick bei statischen gedruckten Paaren ist, die Augen zu entspannen, bis die beiden Bilder \xfcbereinanderliegen, sodass die Abweichung zu flackern scheint.",duration:"Kurze Sitzungen funktionieren am besten: zehn bis f\xfcnfzehn Minuten, ein paar Mal pro Woche, reichen v\xf6llig. Wie bei den meisten visuellen R\xe4tseln z\xe4hlt die Qualit\xe4t der Aufmerksamkeit weit mehr als stundenlanges \xdcben, und m\xfcdes, achtloses Absuchen bringt dir wenig.",research:"Am besten belegt ist genau das, was man erwarten w\xfcrde: Du wirst schneller und genauer beim Finden von Unterschieden, und es gibt eine gewisse \xdcbertragung auf verwandte visuelle Suchaufgaben. Studien zum zugrunde liegenden Paradigma der Ver\xe4nderungserkennung berichten \xfcberwiegend von engen, aufgabenspezifischen Verbesserungen mit nur bescheidenem Transfer, und die verbreiteten Vorstellungen, es steigere die allgemeine Intelligenz oder beuge dem geistigen Abbau vor, sind nicht belegt \u2013 diese gro\xdfen Versprechen also mit Vorsicht genie\xdfen.",rec:"W\xe4hle eine Suchroute und halte sie jede Runde ein, statt aufs Geratewohl zu suchen, dann findest du die \xc4nderungen schneller und \xfcbersiehst weniger davon.",faq:[["Ist es ein Zeichen h\xf6herer Intelligenz, Unterschiede schneller zu finden?","Nein. Es zeigt vor allem, dass du diese Art der visuellen Suche ge\xfcbt hast; es ist eine trainierte Fertigkeit, kein Ma\xdf f\xfcr allgemeine Intelligenz."],["Verbessert es meine allt\xe4gliche Aufmerksamkeit und mein Ged\xe4chtnis?","Es verbessert verl\xe4sslich, wie gut du visuelle \xc4nderungen erkennst, aber ein breiter Transfer auf allt\xe4gliche Aufmerksamkeit oder Ged\xe4chtnis ist schwach und unbelegt \u2013 genie\xdfe es also als gute \xdcbung f\xfcr sorgf\xe4ltiges Hinsehen, nicht als Mittel gegen Konzentrationsprobleme."],["Ich komme nicht weiter und finde den letzten Unterschied nicht. Was hilft?","H\xf6r auf, planlos zu suchen. Decke ein Bild ab, untersuche das andere Bereich f\xfcr Bereich, wechsle dann und pr\xfcfe die Stellen, die man am h\xe4ufigsten \xfcbersieht: Ecken, Hintergr\xfcnde und sich wiederholende Texturen."]],variants:"Zu den Varianten z\xe4hlen Runden auf Zeit, eine feste Anzahl von Unterschieden gegen\xfcber Finde-sie-alle, Fotopaare gegen\xfcber Comic-Illustrationen, bewegte oder animierte Szenen, Wimmelbild-Suchen sowie zoombare, detailreiche Bilder, die geduldiges, sorgf\xe4ltiges Vergleichen belohnen."},pt:{about:"Find Differences mostra duas imagens quase id\xeanticas lado a lado, e seu trabalho \xe9 localizar cada pequena altera\xe7\xe3o entre elas, tocando cada diferen\xe7a \xe0 medida que a encontra. As mudan\xe7as s\xe3o deliberadamente sutis: um bot\xe3o que sumiu, um objeto que mudou de cor, uma folha a mais, uma forma que se deslocou um pouco.",benefit:"Treina a aten\xe7\xe3o visual focada e a busca visual sistem\xe1tica, a capacidade de comparar duas cenas detalhe por detalhe e de perceber uma mudan\xe7a que o olho normalmente passaria batido. Tamb\xe9m depende da mem\xf3ria de trabalho visual, porque voc\xea segura por um instante uma imagem na cabe\xe7a enquanto examina a outra.",history:"O \"ache a diferen\xe7a\" nasceu da tradi\xe7\xe3o dos passatempos impressos e das hist\xf3rias em quadrinhos do s\xe9culo XX, aparecendo em livros de atividades infantis, nas p\xe1ginas de passatempo dos jornais e nas contracapas de revistas. Espalhou-se pelo mundo como um entretenimento barato e sem barreira de idioma, e depois migrou naturalmente para computadores, celulares e sites de jogos casuais.",creator:"N\xe3o tem um \xfanico inventor. \xc9 um g\xeanero tradicional de livros de passatempo e jornais, lapidado por incont\xe1veis ilustradores e editores de passatempos, em vez de creditado a uma pessoa ou a um ano, ent\xe3o qualquer alega\xe7\xe3o de um criador com nome pr\xf3prio deve ser vista com desconfian\xe7a.",methods:"Trabalhe numa ordem fixa em vez de ficar pulando de um lado para o outro: varra da esquerda para a direita, de cima para baixo, ou divida cada imagem em quadrantes e resolva um de cada vez. Compare diretamente as regi\xf5es correspondentes das duas figuras e preste aten\xe7\xe3o especial \xe0s bordas, aos fundos e aos padr\xf5es repetidos, onde as mudan\xe7as melhor se escondem. Um truque conhecido com pares impressos est\xe1ticos \xe9 relaxar os olhos at\xe9 que as duas imagens se sobreponham, fazendo a diferen\xe7a parecer piscar.",duration:"Sess\xf5es curtas funcionam melhor: dez a quinze minutos, algumas vezes por semana, j\xe1 basta. Como na maioria dos passatempos visuais, a qualidade da aten\xe7\xe3o importa muito mais do que insistir por horas, e uma varredura cansada e descuidada ensina pouco.",research:"A evid\xeancia \xe9 mais forte exatamente para o que se esperaria: voc\xea fica mais r\xe1pido e mais preciso em achar diferen\xe7as, e h\xe1 alguma transfer\xeancia para tarefas de busca visual relacionadas. Estudos sobre o paradigma de detec\xe7\xe3o de mudan\xe7as que est\xe1 por tr\xe1s disso relatam, em geral, ganhos restritos e espec\xedficos da tarefa, com transfer\xeancia apenas modesta, e as ideias populares de que isso eleva a intelig\xeancia geral ou afasta o decl\xednio cognitivo n\xe3o t\xeam respaldo, ent\xe3o encare essas grandes promessas com cautela.",rec:"Escolha uma rota de varredura e mantenha-a a cada rodada, em vez de ca\xe7ar ao acaso, e voc\xea vai achar as mudan\xe7as mais r\xe1pido e deixar menos passarem.",faq:[["Achar diferen\xe7as mais r\xe1pido \xe9 sinal de intelig\xeancia maior?","N\xe3o. Mostra principalmente que voc\xea praticou esse tipo de busca visual; \xe9 uma habilidade treinada, n\xe3o uma medida de intelig\xeancia geral."],["Vai melhorar minha aten\xe7\xe3o e minha mem\xf3ria no dia a dia?","Ele melhora de forma confi\xe1vel o qu\xe3o bem voc\xea percebe mudan\xe7as visuais, mas a transfer\xeancia ampla para a aten\xe7\xe3o ou a mem\xf3ria do cotidiano \xe9 fraca e n\xe3o comprovada, ent\xe3o aproveite-o como um bom treino para olhar com cuidado, e n\xe3o como uma solu\xe7\xe3o para a concentra\xe7\xe3o."],["Empaquei e n\xe3o consigo achar a \xfaltima diferen\xe7a. O que ajuda?","Pare de varrer ao acaso. Cubra uma imagem, estude a outra regi\xe3o por regi\xe3o, depois troque, e confira os pontos que as pessoas mais ignoram: cantos, fundos e texturas que se repetem."]],variants:"As variantes incluem rodadas cronometradas, um n\xfamero fixo de diferen\xe7as versus \"ache todas\", pares de fotos versus ilustra\xe7\xf5es de desenho animado, cenas em movimento ou animadas, ca\xe7as a objetos escondidos e imagens de alta resolu\xe7\xe3o com zoom que recompensam a compara\xe7\xe3o paciente e cuidadosa."},hi:{about:"\u092b\u093c\u093e\u0907\u0902\u0921 \u0921\u093f\u092b\u093c\u0930\u0947\u0902\u0938\u0947\u0938 \u0906\u092a\u0915\u094b \u0926\u094b \u0932\u0917\u092d\u0917 \u090f\u0915 \u091c\u0948\u0938\u0940 \u0924\u0938\u094d\u0935\u0940\u0930\u0947\u0902 \u0905\u0917\u0932-\u092c\u0917\u0932 \u0926\u093f\u0916\u093e\u0924\u093e \u0939\u0948, \u0914\u0930 \u0906\u092a\u0915\u093e \u0915\u093e\u092e \u0939\u0948 \u0909\u0928\u0915\u0947 \u092c\u0940\u091a \u0915\u093e \u0939\u0930 \u091b\u094b\u091f\u093e \u092c\u0926\u0932\u093e\u0935 \u0922\u0942\u0901\u0922\u0928\u093e \u0914\u0930 \u092e\u093f\u0932\u0924\u0947 \u0939\u0940 \u0909\u0938 \u092a\u0930 \u091f\u0948\u092a \u0915\u0930\u0928\u093e\u0964 \u092c\u0926\u0932\u093e\u0935 \u091c\u093e\u0928-\u092c\u0942\u091d\u0915\u0930 \u0938\u0942\u0915\u094d\u0937\u094d\u092e \u0930\u0916\u0947 \u091c\u093e\u0924\u0947 \u0939\u0948\u0902: \u090f\u0915 \u0917\u093e\u092f\u092c \u092c\u091f\u0928, \u0930\u0902\u0917 \u092c\u0926\u0932\u0940 \u0939\u0941\u0908 \u0915\u094b\u0908 \u091a\u0940\u091c\u093c, \u090f\u0915 \u0905\u0924\u093f\u0930\u093f\u0915\u094d\u0924 \u092a\u0924\u094d\u0924\u093e, \u0925\u094b\u0921\u093c\u0940 \u0938\u0940 \u0916\u093f\u0938\u0915\u0940 \u0939\u0941\u0908 \u0915\u094b\u0908 \u0906\u0915\u0943\u0924\u093f\u0964",benefit:"\u092f\u0939 \u0915\u0947\u0902\u0926\u094d\u0930\u093f\u0924 \u0926\u0943\u0936\u094d\u092f \u0927\u094d\u092f\u093e\u0928 \u0914\u0930 \u0935\u094d\u092f\u0935\u0938\u094d\u0925\u093f\u0924 \u0926\u0943\u0936\u094d\u092f \u0916\u094b\u091c \u0915\u094b \u0938\u093e\u0927\u0924\u093e \u0939\u0948 \u2014 \u0926\u094b \u0926\u0943\u0936\u094d\u092f\u094b\u0902 \u0915\u094b \u090f\u0915-\u090f\u0915 \u0935\u093f\u0936\u0947\u0937\u0924\u093e \u0915\u0947 \u0938\u094d\u0924\u0930 \u092a\u0930 \u092e\u093f\u0932\u093e\u0928\u0947 \u0914\u0930 \u0910\u0938\u0947 \u092c\u0926\u0932\u093e\u0935 \u0915\u094b \u092a\u0915\u0921\u093c\u0928\u0947 \u0915\u0940 \u0915\u094d\u0937\u092e\u0924\u093e \u091c\u093f\u0938\u0947 \u0906\u092a\u0915\u0940 \u0906\u0901\u0916 \u092f\u0942\u0901 \u0939\u0940 \u091b\u094b\u0921\u093c \u0926\u0947\u0924\u0940\u0964 \u092f\u0939 \u0926\u0943\u0936\u094d\u092f \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932 \u0938\u094d\u092e\u0943\u0924\u093f \u092a\u0930 \u092d\u0940 \u091f\u093f\u0915\u093e \u0939\u0948, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u090f\u0915 \u0924\u0938\u094d\u0935\u0940\u0930 \u0915\u094b \u0925\u094b\u0921\u093c\u0940 \u0926\u0947\u0930 \u092e\u0928 \u092e\u0947\u0902 \u0930\u0916\u0924\u0947 \u0939\u0941\u090f \u0906\u092a \u0926\u0942\u0938\u0930\u0940 \u0915\u094b \u0916\u0902\u0917\u093e\u0932\u0924\u0947 \u0939\u0948\u0902\u0964",history:"\u0938\u094d\u092a\u0949\u091f \u0926 \u0921\u093f\u092b\u093c\u0930\u0947\u0902\u0938 \u092c\u0940\u0938\u0935\u0940\u0902 \u0938\u0926\u0940 \u0915\u0940 \u091b\u092a\u0940 \u092a\u0939\u0947\u0932\u093f\u092f\u094b\u0902 \u0914\u0930 \u0915\u0949\u092e\u093f\u0915 \u092a\u0930\u0902\u092a\u0930\u093e \u0938\u0947 \u0928\u093f\u0915\u0932\u093e, \u091c\u094b \u092c\u091a\u094d\u091a\u094b\u0902 \u0915\u0940 \u0917\u0924\u093f\u0935\u093f\u0927\u093f-\u092a\u0941\u0938\u094d\u0924\u0915\u094b\u0902, \u0905\u0916\u093c\u092c\u093e\u0930\u094b\u0902 \u0915\u0947 \u092a\u0939\u0947\u0932\u0940-\u092a\u0928\u094d\u0928\u094b\u0902 \u0914\u0930 \u092a\u0924\u094d\u0930\u093f\u0915\u093e\u0913\u0902 \u0915\u0947 \u0906\u0916\u093c\u093f\u0930\u0940 \u092a\u0943\u0937\u094d\u0920\u094b\u0902 \u092a\u0930 \u0926\u093f\u0916\u0924\u093e \u0925\u093e\u0964 \u092f\u0939 \u090f\u0915 \u0938\u0938\u094d\u0924\u0947, \u092d\u093e\u0937\u093e-\u092e\u0941\u0915\u094d\u0924 \u092e\u0928\u094b\u0930\u0902\u091c\u0928 \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u0926\u0941\u0928\u093f\u092f\u093e \u092d\u0930 \u092e\u0947\u0902 \u092b\u0948\u0932\u093e, \u0914\u0930 \u092c\u093e\u0926 \u092e\u0947\u0902 \u0938\u0939\u091c\u0924\u093e \u0938\u0947 \u0915\u0902\u092a\u094d\u092f\u0942\u091f\u0930\u094b\u0902, \u092b\u093c\u094b\u0928\u094b\u0902 \u0914\u0930 \u0915\u0948\u091c\u093c\u0941\u0905\u0932 \u0917\u0947\u092e \u0938\u093e\u0907\u091f\u094b\u0902 \u092a\u0930 \u0906 \u0917\u092f\u093e\u0964",creator:"\u0907\u0938\u0915\u093e \u0915\u094b\u0908 \u090f\u0915 \u0906\u0935\u093f\u0937\u094d\u0915\u093e\u0930\u0915 \u0928\u0939\u0940\u0902 \u0939\u0948\u0964 \u092f\u0939 \u092a\u0939\u0947\u0932\u0940-\u0915\u093f\u0924\u093e\u092c\u094b\u0902 \u0914\u0930 \u0905\u0916\u093c\u092c\u093e\u0930\u094b\u0902 \u0915\u0940 \u090f\u0915 \u092a\u093e\u0930\u0902\u092a\u0930\u093f\u0915 \u0935\u093f\u0927\u093e \u0939\u0948, \u091c\u093f\u0938\u0947 \u0915\u093f\u0938\u0940 \u090f\u0915 \u0935\u094d\u092f\u0915\u094d\u0924\u093f \u092f\u093e \u090f\u0915 \u0935\u0930\u094d\u0937 \u0915\u094b \u0936\u094d\u0930\u0947\u092f \u0926\u0947\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u0905\u0928\u0917\u093f\u0928\u0924 \u091a\u093f\u0924\u094d\u0930\u0915\u093e\u0930\u094b\u0902 \u0914\u0930 \u092a\u0939\u0947\u0932\u0940-\u0938\u0902\u092a\u093e\u0926\u0915\u094b\u0902 \u0928\u0947 \u0928\u093f\u0916\u093e\u0930\u093e \u0939\u0948 \u2014 \u0907\u0938\u0932\u093f\u090f \u0915\u093f\u0938\u0940 \u0928\u093e\u092e\u093f\u0924 \u0930\u091a\u092f\u093f\u0924\u093e \u0915\u0947 \u0926\u093e\u0935\u0947 \u0915\u094b \u0938\u0902\u0926\u0947\u0939 \u0938\u0947 \u0926\u0947\u0916\u0928\u093e \u091a\u093e\u0939\u093f\u090f\u0964",methods:"\u0907\u0927\u0930-\u0909\u0927\u0930 \u092d\u093e\u0917\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u090f\u0915 \u0924\u092f \u0915\u094d\u0930\u092e \u092e\u0947\u0902 \u0915\u093e\u092e \u0915\u0930\u0947\u0902: \u092c\u093e\u090f\u0901 \u0938\u0947 \u0926\u093e\u090f\u0901, \u090a\u092a\u0930 \u0938\u0947 \u0928\u0940\u091a\u0947 \u091d\u093e\u0921\u093c\u0942 \u092b\u0947\u0930\u0947\u0902, \u092f\u093e \u0939\u0930 \u0924\u0938\u094d\u0935\u0940\u0930 \u0915\u094b \u091a\u093e\u0930 \u0939\u093f\u0938\u094d\u0938\u094b\u0902 \u092e\u0947\u0902 \u092c\u093e\u0901\u091f\u0915\u0930 \u090f\u0915-\u090f\u0915 \u0915\u0930\u0915\u0947 \u0928\u093f\u092a\u091f\u093e\u090f\u0901\u0964 \u0926\u094b\u0928\u094b\u0902 \u0924\u0938\u094d\u0935\u0940\u0930\u094b\u0902 \u0915\u0947 \u092e\u093f\u0932\u0924\u0947-\u091c\u0941\u0932\u0924\u0947 \u0939\u093f\u0938\u094d\u0938\u094b\u0902 \u0915\u0940 \u0938\u0940\u0927\u0940 \u0924\u0941\u0932\u0928\u093e \u0915\u0930\u0947\u0902, \u0914\u0930 \u0915\u093f\u0928\u093e\u0930\u094b\u0902, \u092a\u0943\u0937\u094d\u0920\u092d\u0942\u092e\u093f\u092f\u094b\u0902 \u0924\u0925\u093e \u0926\u094b\u0939\u0930\u093e\u0924\u0947 \u092a\u0948\u091f\u0930\u094d\u0928\u094b\u0902 \u092a\u0930 \u0916\u093c\u093e\u0938 \u0927\u094d\u092f\u093e\u0928 \u0926\u0947\u0902, \u091c\u0939\u093e\u0901 \u092c\u0926\u0932\u093e\u0935 \u0938\u092c\u0938\u0947 \u0905\u091a\u094d\u091b\u0947 \u091b\u093f\u092a\u0924\u0947 \u0939\u0948\u0902\u0964 \u0938\u094d\u0925\u093f\u0930 \u091b\u092a\u0947 \u091c\u094b\u0921\u093c\u094b\u0902 \u092a\u0930 \u090f\u0915 \u091c\u093e\u0928\u0940-\u092e\u093e\u0928\u0940 \u0924\u0930\u0915\u0940\u092c \u0939\u0948 \u0906\u0901\u0916\u094b\u0902 \u0915\u094b \u0922\u0940\u0932\u093e \u091b\u094b\u0921\u093c \u0926\u0947\u0928\u093e \u0924\u093e\u0915\u093f \u0926\u094b\u0928\u094b\u0902 \u0924\u0938\u094d\u0935\u0940\u0930\u0947\u0902 \u090f\u0915-\u0926\u0942\u0938\u0930\u0947 \u092a\u0930 \u091a\u0922\u093c \u091c\u093e\u090f\u0901 \u0914\u0930 \u092c\u0926\u0932\u093e\u0935 \u091d\u093f\u0932\u092e\u093f\u0932\u093e\u0924\u093e \u0926\u093f\u0916\u0947\u0964",duration:"\u091b\u094b\u091f\u0947 \u0938\u0924\u094d\u0930 \u0938\u092c\u0938\u0947 \u0905\u091a\u094d\u091b\u0947 \u0930\u0939\u0924\u0947 \u0939\u0948\u0902: \u0926\u0938 \u0938\u0947 \u092a\u0902\u0926\u094d\u0930\u0939 \u092e\u093f\u0928\u091f, \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u0915\u0941\u091b \u092c\u093e\u0930, \u0915\u093e\u092b\u093c\u0940 \u0939\u0948\u0902\u0964 \u091c\u093c\u094d\u092f\u093e\u0926\u093e\u0924\u0930 \u0926\u0943\u0936\u094d\u092f \u092a\u0939\u0947\u0932\u093f\u092f\u094b\u0902 \u0915\u0940 \u0924\u0930\u0939, \u0927\u094d\u092f\u093e\u0928 \u0915\u0940 \u0917\u0941\u0923\u0935\u0924\u094d\u0924\u093e \u0918\u0902\u091f\u094b\u0902 \u0930\u0917\u0921\u093c\u0928\u0947 \u0938\u0947 \u0915\u0939\u0940\u0902 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u092e\u093e\u092f\u0928\u0947 \u0930\u0916\u0924\u0940 \u0939\u0948, \u0914\u0930 \u0925\u0915\u0940, \u0932\u093e\u092a\u0930\u0935\u093e\u0939 \u0916\u094b\u091c \u0938\u0947 \u0906\u092a \u092c\u0939\u0941\u0924 \u0915\u092e \u0938\u0940\u0916\u0924\u0947 \u0939\u0948\u0902\u0964",research:"\u091c\u093f\u0938\u0915\u0940 \u0905\u092a\u0947\u0915\u094d\u0937\u093e \u0939\u0948, \u092a\u094d\u0930\u092e\u093e\u0923 \u0920\u0940\u0915 \u0909\u0938\u0940 \u0915\u0947 \u0932\u093f\u090f \u0938\u092c\u0938\u0947 \u092e\u091c\u093c\u092c\u0942\u0924 \u0939\u0948\u0902: \u0906\u092a \u0905\u0902\u0924\u0930 \u0922\u0942\u0901\u0922\u0928\u0947 \u092e\u0947\u0902 \u0924\u0947\u091c\u093c \u0914\u0930 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0938\u091f\u0940\u0915 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u092e\u093f\u0932\u0924\u0947-\u091c\u0941\u0932\u0924\u0947 \u0926\u0943\u0936\u094d\u092f-\u0916\u094b\u091c \u0915\u093e\u0930\u094d\u092f\u094b\u0902 \u092e\u0947\u0902 \u0915\u0941\u091b \u0932\u093e\u092d \u092a\u0939\u0941\u0901\u091a\u0924\u093e \u0939\u0948\u0964 \u0905\u0902\u0924\u0930\u094d\u0928\u093f\u0939\u093f\u0924 \u092a\u0930\u093f\u0935\u0930\u094d\u0924\u0928-\u092a\u0939\u091a\u093e\u0928 \u092a\u094d\u0930\u0924\u093f\u092e\u093e\u0928 \u092a\u0930 \u0939\u0941\u090f \u0905\u0927\u094d\u092f\u092f\u0928 \u091c\u093c\u094d\u092f\u093e\u0926\u093e\u0924\u0930 \u0938\u0902\u0915\u0940\u0930\u094d\u0923, \u0915\u093e\u0930\u094d\u092f-\u0935\u093f\u0936\u093f\u0937\u094d\u091f \u0932\u093e\u092d \u0914\u0930 \u092c\u0938 \u092e\u093e\u092e\u0942\u0932\u0940 \u0939\u0938\u094d\u0924\u093e\u0902\u0924\u0930\u0923 \u092c\u0924\u093e\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u092f\u0939 \u0932\u094b\u0915\u092a\u094d\u0930\u093f\u092f \u0927\u093e\u0930\u0923\u093e\u090f\u0901 \u0915\u093f \u0907\u0938\u0938\u0947 \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u092c\u0941\u0926\u094d\u0927\u093f \u092c\u0922\u093c\u0924\u0940 \u0939\u0948 \u092f\u093e \u0938\u0902\u091c\u094d\u091e\u093e\u0928\u093e\u0924\u094d\u092e\u0915 \u0917\u093f\u0930\u093e\u0935\u091f \u0930\u0941\u0915\u0924\u0940 \u0939\u0948, \u0938\u092e\u0930\u094d\u0925\u093f\u0924 \u0928\u0939\u0940\u0902 \u0939\u0948\u0902 \u2014 \u0907\u0938\u0932\u093f\u090f \u0907\u0928 \u092c\u0921\u093c\u0947 \u0935\u093e\u0926\u094b\u0902 \u0915\u094b \u0938\u093e\u0935\u0927\u093e\u0928\u0940 \u0938\u0947 \u0932\u0947\u0902\u0964",rec:"\u0939\u0930 \u0926\u094c\u0930 \u092e\u0947\u0902 \u092f\u093e\u0926\u0943\u091a\u094d\u091b\u093f\u0915 \u0930\u0942\u092a \u0938\u0947 \u0922\u0942\u0901\u0922\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u090f\u0915 \u0916\u094b\u091c-\u092e\u093e\u0930\u094d\u0917 \u091a\u0941\u0928\u0915\u0930 \u0909\u0938\u0940 \u092a\u0930 \u091f\u093f\u0915\u0947 \u0930\u0939\u0947\u0902, \u0924\u094b \u0906\u092a \u092c\u0926\u0932\u093e\u0935 \u0924\u0947\u091c\u093c\u0940 \u0938\u0947 \u092a\u093e\u090f\u0901\u0917\u0947 \u0914\u0930 \u0915\u092e \u091a\u0942\u0915\u0947\u0902\u0917\u0947\u0964",faq:[["\u0915\u094d\u092f\u093e \u0905\u0902\u0924\u0930 \u0924\u0947\u091c\u093c\u0940 \u0938\u0947 \u0922\u0942\u0901\u0922\u0928\u093e \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u092c\u0941\u0926\u094d\u0927\u093f \u0915\u093e \u0938\u0902\u0915\u0947\u0924 \u0939\u0948?","\u0928\u0939\u0940\u0902\u0964 \u092f\u0939 \u092e\u0941\u0916\u094d\u092f\u0924\u0903 \u0926\u093f\u0916\u093e\u0924\u093e \u0939\u0948 \u0915\u093f \u0906\u092a\u0928\u0947 \u0907\u0938 \u0924\u0930\u0939 \u0915\u0940 \u0926\u0943\u0936\u094d\u092f \u0916\u094b\u091c \u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u093f\u092f\u093e \u0939\u0948; \u092f\u0939 \u090f\u0915 \u0938\u0927\u0940 \u0939\u0941\u0908 \u0915\u0941\u0936\u0932\u0924\u093e \u0939\u0948, \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u092c\u0941\u0926\u094d\u0927\u093f \u0915\u093e \u092e\u093e\u092a \u0928\u0939\u0940\u0902\u0964"],["\u0915\u094d\u092f\u093e \u092f\u0939 \u092e\u0947\u0930\u0947 \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0947 \u0927\u094d\u092f\u093e\u0928 \u0914\u0930 \u0938\u094d\u092e\u0943\u0924\u093f \u0915\u094b \u092c\u0947\u0939\u0924\u0930 \u0915\u0930\u0947\u0917\u093e?","\u092f\u0939 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0930\u0942\u092a \u0938\u0947 \u0938\u0941\u0927\u093e\u0930\u0924\u093e \u0939\u0948 \u0915\u093f \u0906\u092a \u0926\u0943\u0936\u094d\u092f \u092c\u0926\u0932\u093e\u0935 \u0915\u093f\u0924\u0928\u0940 \u0905\u091a\u094d\u091b\u0940 \u0924\u0930\u0939 \u092a\u0915\u0921\u093c\u0924\u0947 \u0939\u0948\u0902, \u092a\u0930 \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0947 \u0927\u094d\u092f\u093e\u0928 \u092f\u093e \u0938\u094d\u092e\u0943\u0924\u093f \u0924\u0915 \u0935\u094d\u092f\u093e\u092a\u0915 \u0939\u0938\u094d\u0924\u093e\u0902\u0924\u0930\u0923 \u0915\u092e\u091c\u093c\u094b\u0930 \u0914\u0930 \u0905\u092a\u094d\u0930\u092e\u093e\u0923\u093f\u0924 \u0939\u0948 \u2014 \u0907\u0938\u0932\u093f\u090f \u0907\u0938\u0947 \u0927\u094d\u092f\u093e\u0928 \u0915\u0940 \u0915\u094b\u0908 \u0926\u0935\u093e \u092e\u093e\u0928\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u0938\u093e\u0935\u0927\u093e\u0928\u0940 \u0938\u0947 \u0926\u0947\u0916\u0928\u0947 \u0915\u0947 \u0905\u091a\u094d\u091b\u0947 \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u0906\u0928\u0902\u0926 \u0932\u0947\u0902\u0964"],["\u092e\u0948\u0902 \u0905\u091f\u0915 \u0917\u092f\u093e \u0939\u0942\u0901 \u0914\u0930 \u0906\u0916\u093c\u093f\u0930\u0940 \u0905\u0902\u0924\u0930 \u0928\u0939\u0940\u0902 \u092e\u093f\u0932 \u0930\u0939\u093e\u0964 \u0915\u094d\u092f\u093e \u092e\u0926\u0926 \u0915\u0930\u0947\u0917\u093e?","\u092f\u093e\u0926\u0943\u091a\u094d\u091b\u093f\u0915 \u0916\u0902\u0917\u093e\u0932\u0928\u093e \u092c\u0902\u0926 \u0915\u0930\u0947\u0902\u0964 \u090f\u0915 \u0924\u0938\u094d\u0935\u0940\u0930 \u0922\u0915 \u0932\u0947\u0902, \u0926\u0942\u0938\u0930\u0940 \u0915\u094b \u0939\u093f\u0938\u094d\u0938\u093e-\u0926\u0930-\u0939\u093f\u0938\u094d\u0938\u093e \u0926\u0947\u0916\u0947\u0902, \u092b\u093f\u0930 \u092c\u0926\u0932 \u0932\u0947\u0902, \u0914\u0930 \u0909\u0928 \u091c\u0917\u0939\u094b\u0902 \u0915\u094b \u091c\u093e\u0901\u091a\u0947\u0902 \u091c\u093f\u0928\u094d\u0939\u0947\u0902 \u0932\u094b\u0917 \u0938\u092c\u0938\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0928\u091c\u093c\u0930\u0905\u0902\u0926\u093e\u091c\u093c \u0915\u0930\u0924\u0947 \u0939\u0948\u0902: \u0915\u094b\u0928\u0947, \u092a\u0943\u0937\u094d\u0920\u092d\u0942\u092e\u093f\u092f\u093e\u0901 \u0914\u0930 \u0926\u094b\u0939\u0930\u093e\u0924\u0940 \u092c\u0928\u093e\u0935\u091f\u0947\u0902\u0964"]],variants:"\u0935\u093f\u0935\u093f\u0927\u0924\u093e\u0913\u0902 \u092e\u0947\u0902 \u0938\u092e\u092f-\u0938\u0940\u092e\u093f\u0924 \u0926\u094c\u0930, \u0924\u092f \u0905\u0902\u0924\u0930-\u0938\u0902\u0916\u094d\u092f\u093e \u092c\u0928\u093e\u092e \u0938\u092d\u0940-\u0915\u094b-\u0922\u0942\u0901\u0922\u094b, \u092b\u093c\u094b\u091f\u094b \u091c\u094b\u0921\u093c\u0947 \u092c\u0928\u093e\u092e \u0915\u093e\u0930\u094d\u091f\u0942\u0928 \u091a\u093f\u0924\u094d\u0930, \u091a\u0932\u0924\u0940 \u092f\u093e \u090f\u0928\u093f\u092e\u0947\u091f\u0947\u0921 \u0926\u0943\u0936\u094d\u092f, \u091b\u093f\u092a\u0940-\u0935\u0938\u094d\u0924\u0941 \u0916\u094b\u091c, \u0914\u0930 \u091c\u093c\u0942\u092e \u0939\u094b\u0928\u0947 \u0935\u093e\u0932\u0940 \u092c\u093e\u0930\u0940\u0915 \u0924\u0938\u094d\u0935\u0940\u0930\u0947\u0902 \u0936\u093e\u092e\u093f\u0932 \u0939\u0948\u0902 \u091c\u094b \u0927\u0948\u0930\u094d\u092f\u092a\u0942\u0930\u094d\u0923, \u0938\u093e\u0935\u0927\u093e\u0928 \u0924\u0941\u0932\u0928\u093e \u0915\u093e \u0907\u0928\u093e\u092e \u0926\u0947\u0924\u0940 \u0939\u0948\u0902\u0964"},zh:{about:"\u300a\u627e\u4e0d\u540c\u300b\u5e76\u6392\u5c55\u793a\u4e24\u5e45\u51e0\u4e4e\u5b8c\u5168\u76f8\u540c\u7684\u56fe\u753b\uff0c\u4f60\u7684\u4efb\u52a1\u662f\u627e\u51fa\u5b83\u4eec\u4e4b\u95f4\u7684\u6bcf\u4e00\u5904\u7ec6\u5c0f\u53d8\u5316\uff0c\u6bcf\u53d1\u73b0\u4e00\u5904\u5c31\u70b9\u6309\u4e00\u5904\u3002\u8fd9\u4e9b\u53d8\u5316\u662f\u523b\u610f\u505a\u5f97\u5f88\u5fae\u5999\u7684\uff1a\u5c11\u4e86\u4e00\u9897\u7ebd\u6263\u3001\u67d0\u4e2a\u7269\u4f53\u6362\u4e86\u989c\u8272\u3001\u591a\u51fa\u4e00\u7247\u53f6\u5b50\u3001\u67d0\u4e2a\u5f62\u72b6\u632a\u52a8\u4e86\u4e00\u70b9\u70b9\u3002",benefit:"\u5b83\u8bad\u7ec3\u4e13\u6ce8\u7684\u89c6\u89c9\u6ce8\u610f\u529b\u548c\u7cfb\u7edf\u5316\u7684\u89c6\u89c9\u641c\u7d22\uff0c\u5373\u9010\u4e2a\u7279\u5f81\u5730\u6bd4\u5bf9\u4e24\u5e45\u753b\u9762\u3001\u5e76\u6ce8\u610f\u5230\u90a3\u4e9b\u539f\u672c\u4f1a\u88ab\u4f60\u7684\u773c\u775b\u7565\u8fc7\u7684\u53d8\u5316\u7684\u80fd\u529b\u3002\u5b83\u4e5f\u4f9d\u8d56\u89c6\u89c9\u5de5\u4f5c\u8bb0\u5fc6\uff0c\u56e0\u4e3a\u4f60\u8981\u5728\u626b\u89c6\u4e00\u5e45\u56fe\u65f6\u628a\u53e6\u4e00\u5e45\u56fe\u77ed\u6682\u5730\u8bb0\u5728\u8111\u4e2d\u3002",history:"\u627e\u4e0d\u540c\u8131\u80ce\u4e8e 20 \u4e16\u7eaa\u7684\u5370\u5237\u8c1c\u9898\u4e0e\u6f2b\u753b\u4f20\u7edf\uff0c\u51fa\u73b0\u5728\u513f\u7ae5\u6d3b\u52a8\u624b\u518c\u3001\u62a5\u7eb8\u8c1c\u9898\u7248\u548c\u6742\u5fd7\u672b\u9875\u4e0a\u3002\u5b83\u4f5c\u4e3a\u4e00\u79cd\u5ec9\u4ef7\u3001\u65e0\u8bed\u8a00\u95e8\u69db\u7684\u6d88\u9063\u4f20\u904d\u4e16\u754c\uff0c\u540e\u6765\u53c8\u81ea\u7136\u800c\u7136\u5730\u79fb\u690d\u5230\u7535\u8111\u3001\u624b\u673a\u548c\u4f11\u95f2\u6e38\u620f\u7f51\u7ad9\u4e0a\u3002",creator:"\u5b83\u6ca1\u6709\u5355\u4e00\u7684\u53d1\u660e\u8005\u3002\u5b83\u662f\u4e00\u79cd\u4f20\u7edf\u7684\u8c1c\u9898\u4e66\u4e0e\u62a5\u7eb8\u4f53\u88c1\uff0c\u7531\u65e0\u6570\u63d2\u753b\u5e08\u548c\u8c1c\u9898\u7f16\u8f91\u6253\u78e8\u800c\u6210\uff0c\u800c\u975e\u5f52\u529f\u4e8e\u67d0\u4e00\u4e2a\u4eba\u6216\u67d0\u4e00\u5e74\uff0c\u6240\u4ee5\u4efb\u4f55\u6307\u540d\u9053\u59d3\u7684\u521b\u5236\u8005\u8bf4\u6cd5\u90fd\u5e94\u5f53\u5b58\u7591\u3002",methods:"\u6309\u56fa\u5b9a\u987a\u5e8f\u4f5c\u4e1a\uff0c\u800c\u4e0d\u662f\u56db\u5904\u4e71\u770b\uff1a\u4ece\u5de6\u5230\u53f3\u3001\u4ece\u4e0a\u5230\u4e0b\u5730\u626b\uff0c\u6216\u628a\u6bcf\u5e45\u56fe\u5206\u6210\u56db\u4e2a\u8c61\u9650\u3001\u9010\u4e00\u6e05\u67e5\u3002\u76f4\u63a5\u6bd4\u5bf9\u4e24\u5e45\u56fe\u4e2d\u76f8\u5bf9\u5e94\u7684\u533a\u57df\uff0c\u5e76\u5bf9\u8fb9\u7f18\u3001\u80cc\u666f\u548c\u91cd\u590d\u56fe\u6848\u683c\u5916\u7559\u5fc3\u2014\u2014\u53d8\u5316\u6700\u7231\u85cf\u5728\u90a3\u91cc\u3002\u5bf9\u9759\u6001\u5370\u5237\u56fe\u5bf9\u8fd8\u6709\u4e00\u4e2a\u5df2\u77e5\u7684\u5c0f\u7a8d\u95e8\uff1a\u653e\u677e\u53cc\u773c\uff0c\u76f4\u5230\u4e24\u5e45\u56fe\u91cd\u53e0\uff0c\u8fd9\u6837\u5dee\u5f02\u5c31\u4f1a\u50cf\u5728\u95ea\u70c1\u4e00\u6837\u5192\u51fa\u6765\u3002",duration:"\u77ed\u65f6\u6bb5\u6700\u6709\u6548\uff1a\u5341\u5230\u5341\u4e94\u5206\u949f\uff0c\u6bcf\u5468\u51e0\u6b21\uff0c\u5c31\u8db3\u591f\u4e86\u3002\u548c\u5927\u591a\u6570\u89c6\u89c9\u8c1c\u9898\u4e00\u6837\uff0c\u6ce8\u610f\u529b\u7684\u8d28\u91cf\u8fdc\u6bd4\u8fde\u8017\u6570\u5c0f\u65f6\u66f4\u91cd\u8981\uff0c\u800c\u75b2\u60eb\u3001\u9a6c\u864e\u7684\u626b\u89c6\u6559\u4e0d\u4f1a\u4f60\u4ec0\u4e48\u3002",research:"\u8bc1\u636e\u6700\u5145\u5206\u7684\u6070\u6070\u662f\u4f60\u80fd\u9884\u6599\u5230\u7684\u90e8\u5206\uff1a\u4f60\u5728\u627e\u4e0d\u540c\u4e0a\u4f1a\u53d8\u5f97\u66f4\u5feb\u3001\u66f4\u51c6\uff0c\u5e76\u4e14\u5bf9\u76f8\u5173\u7684\u89c6\u89c9\u641c\u7d22\u4efb\u52a1\u6709\u4e00\u5b9a\u7684\u8fc1\u79fb\u3002\u9488\u5bf9\u5176\u80cc\u540e\u7684\u201c\u53d8\u5316\u89c9\u5bdf\u201d\u8303\u5f0f\u7684\u7814\u7a76\u5927\u591a\u62a5\u544a\u7684\u662f\u72ed\u7a84\u3001\u4efb\u52a1\u7279\u5b9a\u7684\u6536\u76ca\uff0c\u8fc1\u79fb\u5e45\u5ea6\u6709\u9650\uff0c\u800c\u90a3\u4e9b\u6d41\u884c\u7684\u201c\u5b83\u80fd\u63d0\u5347\u6574\u4f53\u667a\u529b\u6216\u62b5\u5fa1\u8ba4\u77e5\u8870\u9000\u201d\u7684\u60f3\u6cd5\u5e76\u65e0\u652f\u6301\uff0c\u6240\u4ee5\u5bf9\u90a3\u4e9b\u5b8f\u5927\u627f\u8bfa\u8981\u4fdd\u6301\u8c28\u614e\u3002",rec:"\u9009\u5b9a\u4e00\u6761\u626b\u89c6\u8def\u7ebf\uff0c\u6bcf\u4e00\u8f6e\u90fd\u575a\u6301\u8d70\u5b83\uff0c\u800c\u4e0d\u662f\u6f2b\u65e0\u76ee\u7684\u5730\u4e71\u627e\uff0c\u8fd9\u6837\u4f60\u4f1a\u66f4\u5feb\u627e\u5230\u53d8\u5316\u3001\u4e5f\u66f4\u5c11\u9057\u6f0f\u3002",faq:[["\u66f4\u5feb\u627e\u51fa\u4e0d\u540c\u662f\u4e0d\u662f\u667a\u529b\u66f4\u9ad8\u7684\u6807\u5fd7\uff1f","\u4e0d\u662f\u3002\u5b83\u4e3b\u8981\u8868\u660e\u4f60\u7ec3\u8fc7\u8fd9\u7c7b\u89c6\u89c9\u641c\u7d22\uff1b\u8fd9\u662f\u4e00\u9879\u7ec3\u51fa\u6765\u7684\u6280\u80fd\uff0c\u800c\u975e\u8861\u91cf\u6574\u4f53\u667a\u529b\u7684\u5c3a\u5ea6\u3002"],["\u5b83\u4f1a\u6539\u5584\u6211\u65e5\u5e38\u7684\u6ce8\u610f\u529b\u548c\u8bb0\u5fc6\u5417\uff1f","\u5b83\u80fd\u53ef\u9760\u5730\u63d0\u5347\u4f60\u53d1\u73b0\u89c6\u89c9\u53d8\u5316\u7684\u672c\u9886\uff0c\u4f46\u5411\u65e5\u5e38\u6ce8\u610f\u529b\u6216\u8bb0\u5fc6\u7684\u5e7f\u6cdb\u8fc1\u79fb\u5f88\u5f31\u3001\u4e5f\u672a\u7ecf\u8bc1\u5b9e\uff0c\u6240\u4ee5\u8bf7\u628a\u5b83\u5f53\u4f5c\u4ed4\u7ec6\u89c2\u5bdf\u7684\u597d\u7ec3\u4e60\u6765\u4eab\u53d7\uff0c\u800c\u975e\u4e13\u6ce8\u529b\u7684\u89e3\u836f\u3002"],["\u6211\u5361\u4f4f\u4e86\uff0c\u627e\u4e0d\u5230\u6700\u540e\u4e00\u5904\u4e0d\u540c\u3002\u600e\u4e48\u529e\uff1f","\u522b\u518d\u968f\u610f\u4e71\u626b\u4e86\u3002\u76d6\u4f4f\u4e00\u5e45\u56fe\uff0c\u9010\u533a\u7814\u7a76\u53e6\u4e00\u5e45\uff0c\u7136\u540e\u4ea4\u6362\uff0c\u518d\u53bb\u67e5\u90a3\u4e9b\u4eba\u4eec\u6700\u5e38\u5ffd\u7565\u7684\u5730\u65b9\uff1a\u89d2\u843d\u3001\u80cc\u666f\u548c\u91cd\u590d\u7684\u7eb9\u7406\u3002"]],variants:"\u53d8\u4f53\u5305\u62ec\u8ba1\u65f6\u56de\u5408\u3001\u56fa\u5b9a\u5dee\u5f02\u6570\u91cf\u4e0e\u201c\u5168\u90e8\u627e\u51fa\u201d\u7684\u5bf9\u6bd4\u3001\u7167\u7247\u56fe\u5bf9\u4e0e\u5361\u901a\u63d2\u753b\u7684\u5bf9\u6bd4\u3001\u79fb\u52a8\u6216\u52a8\u753b\u573a\u666f\u3001\u9690\u85cf\u7269\u641c\u5bfb\uff0c\u4ee5\u53ca\u5956\u52b1\u8010\u5fc3\u7ec6\u81f4\u6bd4\u5bf9\u7684\u53ef\u7f29\u653e\u9ad8\u7ec6\u8282\u56fe\u50cf\u3002"}},flanker:{ru:{about:"\u0426\u0435\u043d\u0442\u0440\u0430\u043b\u044c\u043d\u0430\u044f \u0441\u0442\u0440\u0435\u043b\u043a\u0430 \u043e\u043a\u0440\u0443\u0436\u0435\u043d\u0430 \u0441\u043e\u0441\u0435\u0434\u043d\u0438\u043c\u0438, \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u0441\u043c\u043e\u0442\u0440\u044f\u0442 \u0442\u0443\u0434\u0430 \u0436\u0435 (\u0441\u043e\u0432\u043f\u0430\u0434\u0435\u043d\u0438\u0435) \u0438\u043b\u0438 \u0432 \u043f\u0440\u043e\u0442\u0438\u0432\u043e\u043f\u043e\u043b\u043e\u0436\u043d\u0443\u044e \u0441\u0442\u043e\u0440\u043e\u043d\u0443 (\u043a\u043e\u043d\u0444\u043b\u0438\u043a\u0442). \u0420\u0435\u0430\u0433\u0438\u0440\u0443\u0435\u0448\u044c \u0442\u043e\u043b\u044c\u043a\u043e \u043d\u0430 \u0446\u0435\u043d\u0442\u0440\u0430\u043b\u044c\u043d\u0443\u044e \u2014 \u0430 \u0441\u043e\u0441\u0435\u0434\u043d\u0438\u0435 \u043c\u0435\u0448\u0430\u044e\u0442, \u043a\u043e\u0433\u0434\u0430 \u043d\u0435 \u0441\u043e\u0433\u043b\u0430\u0441\u043d\u044b.",benefit:"\u0418\u0437\u0431\u0438\u0440\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0435 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u0438 \u0442\u043e\u0440\u043c\u043e\u0436\u0435\u043d\u0438\u0435 \u0440\u0435\u0430\u043a\u0446\u0438\u0438 \u2014 \u0443\u0434\u0435\u0440\u0436\u0430\u043d\u0438\u0435 \u0444\u043e\u043a\u0443\u0441\u0430 \u043d\u0430 \u0446\u0435\u043b\u0438 \u043f\u0440\u0438 \u043f\u043e\u0434\u0430\u0432\u043b\u0435\u043d\u0438\u0438 \u043f\u043e\u043c\u0435\u0445 \u043e\u0442 \u043e\u0442\u0432\u043b\u0435\u043a\u0430\u044e\u0449\u0438\u0445 \u043f\u0440\u044f\u043c\u043e \u0440\u044f\u0434\u043e\u043c.",history:"\u0412\u0432\u0435\u0434\u0435\u043d\u0430 \u0432 1974-\u043c \u0438 \u0441\u0442\u0430\u043b\u0430 \u043e\u0434\u043d\u043e\u0439 \u0438\u0437 \u0432\u0430\u0436\u043d\u0435\u0439\u0448\u0438\u0445 \u0437\u0430\u0434\u0430\u0447 \u043a\u043e\u0433\u043d\u0438\u0442\u0438\u0432\u043d\u043e\u0439 \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u0438 \u0434\u043b\u044f \u0438\u0437\u0443\u0447\u0435\u043d\u0438\u044f \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f \u0438 \u043a\u043e\u043d\u043a\u0443\u0440\u0435\u043d\u0446\u0438\u0438 \u0440\u0435\u0430\u043a\u0446\u0438\u0439; \u0432\u0445\u043e\u0434\u0438\u0442 \u0432 \u0441\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u044b\u0435 \u0442\u0435\u0441\u0442\u044b \u0441\u0435\u0442\u0435\u0439 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f.",creator:"\u0411\u0430\u0440\u0431\u0430\u0440\u0430 \u0438 \u0427\u0430\u0440\u043b\u044c\u0437 \u042d\u0440\u0438\u043a\u0441\u0435\u043d \u2014 \u043e\u043f\u0443\u0431\u043b\u0438\u043a\u043e\u0432\u0430\u043b\u0438 flanker-\u0437\u0430\u0434\u0430\u0447\u0443 \u0432 1974 \u0433\u043e\u0434\u0443 (Perception & Psychophysics).",methods:"\u0417\u0430\u0444\u0438\u043a\u0441\u0438\u0440\u0443\u0439\u0441\u044f \u043d\u0430 \u0446\u0435\u043d\u0442\u0440\u0435 \u0438 \u0441\u0447\u0438\u0442\u0430\u0439 \u0441\u043e\u0441\u0435\u0434\u043d\u0438\u0435 \u0448\u0443\u043c\u043e\u043c. \u0421\u043b\u0435\u0434\u0438 \u0437\u0430 \u044d\u0444\u0444\u0435\u043a\u0442\u043e\u043c \u043a\u043e\u043d\u0433\u0440\u0443\u044d\u043d\u0442\u043d\u043e\u0441\u0442\u0438 \u2014 \u043b\u0438\u0448\u043d\u0438\u043c \u0432\u0440\u0435\u043c\u0435\u043d\u0435\u043c \u043d\u0430 \u043a\u043e\u043d\u0444\u043b\u0438\u043a\u0442\u043d\u044b\u0445 \u043f\u0440\u043e\u0431\u0430\u0445 \u2014 \u0438 \u0441\u0442\u0430\u0440\u0430\u0439\u0441\u044f \u0441\u043e\u043a\u0440\u0430\u0449\u0430\u0442\u044c \u0435\u0433\u043e \u0431\u0435\u0437 \u043f\u043e\u0442\u0435\u0440\u0438 \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u0438.",duration:"\u041a\u043e\u0440\u043e\u0442\u043a\u0438\u0435 \u0431\u043b\u043e\u043a\u0438 \u043f\u043e \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u043c\u0438\u043d\u0443\u0442. \u0426\u0435\u043d\u0430 \u043a\u043e\u043d\u0444\u043b\u0438\u043a\u0442\u0430 \u043e\u0431\u044b\u0447\u043d\u043e \u043f\u0430\u0434\u0430\u0435\u0442 \u0440\u0430\u043d\u043e, \u043f\u043e\u0442\u043e\u043c \u0441\u0442\u0430\u0431\u0438\u043b\u0438\u0437\u0438\u0440\u0443\u0435\u0442\u0441\u044f.",research:"\u041d\u0430\u0434\u0451\u0436\u043d\u044b\u0439, \u043c\u043d\u043e\u0433\u043e\u043a\u0440\u0430\u0442\u043d\u043e \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u0435\u0434\u0451\u043d\u043d\u044b\u0439 \u044d\u0444\u0444\u0435\u043a\u0442. \u0422\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0430 \u0441\u043d\u0438\u0436\u0430\u0435\u0442 \u043f\u043e\u043c\u0435\u0445\u0443 \u0432 \u0441\u0430\u043c\u043e\u0439 \u0437\u0430\u0434\u0430\u0447\u0435; \u043a\u0430\u043a \u0438 \u0443 \u0434\u0440\u0443\u0433\u0438\u0445 \u043a\u043e\u043d\u0444\u043b\u0438\u043a\u0442\u043d\u044b\u0445 \u0437\u0430\u0434\u0430\u0447, \u043f\u0435\u0440\u0435\u043d\u043e\u0441 \u043d\u0430 \u0431\u044b\u0442\u043e\u0432\u0443\u044e \u043a\u043e\u043d\u0446\u0435\u043d\u0442\u0440\u0430\u0446\u0438\u044e \u0434\u043e\u043a\u0430\u0437\u0430\u043d \u0441\u043b\u0430\u0431\u043e \u2014 \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0439 \u0440\u0430\u0434\u0438 \u043a\u043e\u043d\u043a\u0440\u0435\u0442\u043d\u043e\u0433\u043e \u043d\u0430\u0432\u044b\u043a\u0430.",rec:"\u0418\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0439, \u0447\u0442\u043e\u0431\u044b \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u0443\u0437\u043a\u0438\u0439 \u0444\u043e\u043a\u0443\u0441, \u0443\u0441\u0442\u043e\u0439\u0447\u0438\u0432\u044b\u0439 \u043a \u043e\u0442\u0432\u043b\u0435\u043a\u0430\u044e\u0449\u0438\u043c. \u0414\u0435\u0440\u0436\u0438 \u0432\u044b\u0441\u043e\u043a\u0443\u044e \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u044c; \u0446\u0435\u043b\u044c \u2014 \u0443\u0441\u0442\u043e\u044f\u0442\u044c \u043f\u0440\u043e\u0442\u0438\u0432 \u0441\u043e\u0441\u0435\u0434\u043d\u0438\u0445 \u0441\u0442\u0440\u0435\u043b\u043e\u043a, \u0430 \u043d\u0435 \u0441\u043b\u0435\u043f\u0430\u044f \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c.",faq:[["\u0427\u0442\u043e \u0442\u0430\u043a\u043e\u0435 \u044d\u0444\u0444\u0435\u043a\u0442 \u0444\u043b\u0430\u043d\u043a\u0435\u0440\u043e\u0432?","\u0422\u044b \u043c\u0435\u0434\u043b\u0435\u043d\u043d\u0435\u0435 \u0438 \u043c\u0435\u043d\u0435\u0435 \u0442\u043e\u0447\u0435\u043d, \u043a\u043e\u0433\u0434\u0430 \u043e\u043a\u0440\u0443\u0436\u0430\u044e\u0449\u0438\u0435 \u0441\u0442\u0440\u0435\u043b\u043a\u0438 \u0441\u043c\u043e\u0442\u0440\u044f\u0442 \u043f\u0440\u043e\u0442\u0438\u0432 \u0446\u0435\u043d\u0442\u0440\u0430\u043b\u044c\u043d\u043e\u0439 \u0446\u0435\u043b\u0438."],["\u0427\u0442\u043e \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442?","\u0418\u0437\u0431\u0438\u0440\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0435 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u0438 \u0441\u043f\u043e\u0441\u043e\u0431\u043d\u043e\u0441\u0442\u044c \u0442\u043e\u0440\u043c\u043e\u0437\u0438\u0442\u044c \u0431\u043b\u0438\u0437\u043a\u0438\u0435 \u043e\u0442\u0432\u043b\u0435\u043a\u0430\u044e\u0449\u0438\u0435."],["\u0421\u0442\u0440\u0435\u043b\u043a\u0438 \u0438\u043b\u0438 \u0431\u0443\u043a\u0432\u044b?","\u0415\u0441\u0442\u044c \u043e\u0431\u0430 \u2014 \u043a\u043b\u0430\u0441\u0441\u0438\u043a\u0430 \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u043b\u0430 \u0431\u0443\u043a\u0432\u044b; \u0441\u0442\u0440\u0435\u043b\u043a\u0438 \u044d\u0442\u043e \u0440\u0430\u0441\u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0451\u043d\u043d\u0430\u044f \u0441\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u0430\u044f \u0444\u043e\u0440\u043c\u0430."]],variants:"\u0421\u0442\u0440\u0435\u043b\u043e\u0447\u043d\u044b\u0435, \u0431\u0443\u043a\u0432\u0435\u043d\u043d\u044b\u0435 \u0438 \u0446\u0432\u0435\u0442\u043e\u0432\u044b\u0435 \u0444\u043b\u0430\u043d\u043a\u0435\u0440\u044b; \u0440\u0430\u0437\u043d\u043e\u0435 \u0440\u0430\u0441\u0441\u0442\u043e\u044f\u043d\u0438\u0435 \u0434\u043e \u0441\u043e\u0441\u0435\u0434\u043d\u0438\u0445; \u043a\u043e\u043c\u0431\u0438\u043d\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u044b\u0435 \u0431\u0430\u0442\u0430\u0440\u0435\u0438 \u043a\u043e\u043d\u0444\u043b\u0438\u043a\u0442\u0430 \u0432\u0440\u043e\u0434\u0435 \u0442\u0435\u0441\u0442\u043e\u0432 \u0441\u0435\u0442\u0435\u0439 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f."},en:{about:"A central arrow is surrounded by flanking arrows that point the same way (congruent) or the opposite way (incongruent). You respond to the centre one only \u2014 and the flankers fight you when they disagree.",benefit:"Selective attention and response inhibition \u2014 focusing on a target while suppressing interference from distractors right next to it.",history:"Introduced in 1974, it became one of the most important tasks in cognitive psychology for studying attention and response competition, and is a core part of modern attention-network testing.",creator:"Barbara and Charles Eriksen, who published the flanker task in 1974 (Perception & Psychophysics).",methods:"Lock onto the centre and treat the flankers as noise. Watch your congruency effect \u2014 the extra time on incongruent trials \u2014 and aim to shrink it without sacrificing accuracy.",duration:"Short blocks, a few minutes at a time. Expect your congruency cost to fall early and then stabilise.",research:"A robust, heavily replicated effect. Training lowers your interference on the task itself; like other conflict tasks, evidence for broad transfer to everyday focus is limited \u2014 train it for the specific skill.",rec:"Use it to practise narrow, distractor-proof focus. Keep accuracy high; the goal is resisting the flankers, not blind speed.",faq:[["What is the flanker effect?","You are slower and less accurate when the surrounding arrows point opposite to the central target."],["What does it train?","Selective attention and the ability to inhibit nearby distractors."],["Arrows or letters?","Both exist \u2014 the classic version used letters; arrows are the common modern form."]],variants:"Arrow, letter and colour flankers; varying flanker distance; and combined conflict batteries such as attention-network tests."},es:{about:"Una flecha central est\xe1 rodeada de flechas flanqueantes que apuntan en el mismo sentido (congruentes) o en el sentido opuesto (incongruentes). Respondes solo a la del centro, y las flanqueantes te entorpecen cuando no coinciden.",benefit:"Atenci\xf3n selectiva e inhibici\xf3n de la respuesta: concentrarte en un objetivo mientras suprimes la interferencia de los distractores que tiene justo al lado.",history:"Presentada en 1974, se convirti\xf3 en una de las tareas m\xe1s importantes de la psicolog\xeda cognitiva para estudiar la atenci\xf3n y la competencia entre respuestas, y es una pieza central de las pruebas modernas de redes atencionales.",creator:"Barbara y Charles Eriksen, que publicaron la tarea de flancos en 1974 (Perception & Psychophysics).",methods:"F\xedjate en el centro y trata las flanqueantes como ruido. Vigila tu efecto de congruencia (el tiempo extra en los ensayos incongruentes) y procura reducirlo sin sacrificar la precisi\xf3n.",duration:"Bloques cortos, de unos pocos minutos cada vez. Espera que tu coste de congruencia baje pronto y luego se estabilice.",research:"Un efecto robusto y muy replicado. El entrenamiento reduce tu interferencia en la propia tarea; como en otras tareas de conflicto, la evidencia de una transferencia amplia a la concentraci\xf3n cotidiana es limitada: entr\xe9nalo por la destreza espec\xedfica.",rec:"\xdasalo para practicar una concentraci\xf3n estrecha y a prueba de distractores. Mant\xe9n alta la precisi\xf3n; el objetivo es resistir a las flanqueantes, no la velocidad ciega.",faq:[["\xbfQu\xe9 es el efecto de flancos?","Eres m\xe1s lento y menos preciso cuando las flechas que rodean al objetivo central apuntan en sentido opuesto a \xe9l."],["\xbfQu\xe9 entrena?","La atenci\xf3n selectiva y la capacidad de inhibir los distractores cercanos."],["\xbfFlechas o letras?","Existen ambas: la versi\xf3n cl\xe1sica usaba letras; las flechas son la forma moderna m\xe1s habitual."]],variants:"Flancos de flechas, de letras y de colores; distancia variable de los flancos; y bater\xedas de conflicto combinadas, como las pruebas de redes atencionales."},de:{about:"Ein zentraler Pfeil ist von flankierenden Pfeilen umgeben, die in dieselbe Richtung (kongruent) oder in die entgegengesetzte Richtung (inkongruent) zeigen. Du reagierst nur auf den mittleren \u2013 und die Flanker arbeiten gegen dich, wenn sie nicht \xfcbereinstimmen.",benefit:"Selektive Aufmerksamkeit und Reaktionshemmung \u2013 sich auf ein Ziel zu konzentrieren und zugleich die St\xf6rung durch unmittelbar daneben liegende Ablenker zu unterdr\xfccken.",history:"1974 eingef\xfchrt, wurde sie zu einer der wichtigsten Aufgaben der Kognitionspsychologie f\xfcr die Untersuchung von Aufmerksamkeit und Reaktionskonkurrenz und ist heute ein Kernbestandteil der modernen Aufmerksamkeitsnetzwerk-Tests.",creator:"Barbara und Charles Eriksen, die die Flanker-Aufgabe 1974 ver\xf6ffentlichten (Perception & Psychophysics).",methods:"Fixiere die Mitte und behandle die Flanker als Rauschen. Achte auf deinen Kongruenzeffekt \u2013 die zus\xe4tzliche Zeit bei inkongruenten Durchg\xe4ngen \u2013 und versuche, ihn zu verkleinern, ohne Genauigkeit zu opfern.",duration:"Kurze Bl\xf6cke, ein paar Minuten am St\xfcck. Rechne damit, dass deine Kongruenzkosten fr\xfch fallen und sich dann einpendeln.",research:"Ein robuster, vielfach replizierter Effekt. Training senkt deine St\xf6ranf\xe4lligkeit in der Aufgabe selbst; wie bei anderen Konfliktaufgaben sind die Belege f\xfcr eine breite \xdcbertragung auf die allt\xe4gliche Konzentration begrenzt \u2013 trainiere es f\xfcr die spezifische F\xe4higkeit.",rec:"Nutze es, um einen engen, ablenkungssicheren Fokus zu \xfcben. Halte die Genauigkeit hoch; das Ziel ist, den Flankern zu widerstehen, nicht blindes Tempo.",faq:[["Was ist der Flanker-Effekt?","Du bist langsamer und ungenauer, wenn die umgebenden Pfeile in die entgegengesetzte Richtung zum zentralen Ziel zeigen."],["Was trainiert es?","Die selektive Aufmerksamkeit und die F\xe4higkeit, nahe Ablenker zu hemmen."],["Pfeile oder Buchstaben?","Beides gibt es \u2013 die klassische Version nutzte Buchstaben; Pfeile sind die g\xe4ngige moderne Form."]],variants:"Pfeil-, Buchstaben- und Farb-Flanker; unterschiedlicher Flanker-Abstand; sowie kombinierte Konflikt-Testbatterien wie die Aufmerksamkeitsnetzwerk-Tests."},pt:{about:"Uma seta central \xe9 cercada por setas laterais que apontam para o mesmo lado (congruente) ou para o lado oposto (incongruente). Voc\xea responde apenas \xe0 do centro \u2014 e as laterais brigam com voc\xea quando discordam.",benefit:"Aten\xe7\xe3o seletiva e inibi\xe7\xe3o da resposta \u2014 focar num alvo enquanto suprime a interfer\xeancia dos distratores bem ao lado dele.",history:"Apresentada em 1974, tornou-se uma das tarefas mais importantes da psicologia cognitiva para estudar a aten\xe7\xe3o e a competi\xe7\xe3o entre respostas, e \xe9 parte central dos testes modernos de redes de aten\xe7\xe3o.",creator:"Barbara e Charles Eriksen, que publicaram a tarefa de flanker em 1974 (Perception & Psychophysics).",methods:"Fixe-se na do centro e trate as laterais como ru\xeddo. Observe o seu efeito de congru\xeancia \u2014 o tempo extra nas tentativas incongruentes \u2014 e busque reduzi-lo sem sacrificar a precis\xe3o.",duration:"Blocos curtos, alguns minutos de cada vez. Espere que o seu custo de congru\xeancia caia cedo e depois se estabilize.",research:"Um efeito robusto e muito replicado. O treino reduz a sua interfer\xeancia na pr\xf3pria tarefa; como em outras tarefas de conflito, a evid\xeancia de transfer\xeancia ampla para o foco do dia a dia \xe9 limitada \u2014 treine pela habilidade espec\xedfica.",rec:"Use para praticar um foco estreito e \xe0 prova de distra\xe7\xf5es. Mantenha a precis\xe3o alta; o objetivo \xe9 resistir \xe0s laterais, n\xe3o a velocidade cega.",faq:[["O que \xe9 o efeito flanker?","Voc\xea fica mais lento e menos preciso quando as setas ao redor apontam para o lado oposto ao do alvo central."],["O que isso treina?","A aten\xe7\xe3o seletiva e a capacidade de inibir os distratores pr\xf3ximos."],["Setas ou letras?","Os dois existem \u2014 a vers\xe3o cl\xe1ssica usava letras; as setas s\xe3o a forma moderna comum."]],variants:"Flankers de setas, de letras e de cores; dist\xe2ncia vari\xe1vel das laterais; e baterias combinadas de conflito, como os testes de redes de aten\xe7\xe3o."},hi:{about:"\u092c\u0940\u091a \u092e\u0947\u0902 \u090f\u0915 \u0924\u0940\u0930 \u0939\u094b\u0924\u093e \u0939\u0948, \u0914\u0930 \u0909\u0938\u0915\u0947 \u0926\u094b\u0928\u094b\u0902 \u0913\u0930 \u0915\u0941\u091b \u0914\u0930 \u0924\u0940\u0930 \u0932\u0917\u0947 \u0930\u0939\u0924\u0947 \u0939\u0948\u0902 \u091c\u094b \u092f\u093e \u0924\u094b \u0909\u0938\u0940 \u0926\u093f\u0936\u093e \u092e\u0947\u0902 \u0907\u0936\u093e\u0930\u093e \u0915\u0930\u0924\u0947 \u0939\u0948\u0902 (congruent) \u092f\u093e \u0909\u0932\u091f\u0940 \u0926\u093f\u0936\u093e \u092e\u0947\u0902 (incongruent)\u0964 \u0906\u092a\u0915\u094b \u0938\u093f\u0930\u094d\u092b\u093c \u092c\u0940\u091a \u0935\u093e\u0932\u0947 \u0924\u0940\u0930 \u0915\u0947 \u0939\u093f\u0938\u093e\u092c \u0938\u0947 \u091c\u0935\u093e\u092c \u0926\u0947\u0928\u093e \u0939\u0948 \u2014 \u0914\u0930 \u091c\u092c \u092c\u0917\u0932 \u0935\u093e\u0932\u0947 \u0924\u0940\u0930 \u0909\u0938\u0938\u0947 \u0905\u0938\u0939\u092e\u0924 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902, \u0924\u094b \u0935\u0947 \u0906\u092a\u0915\u094b \u092d\u091f\u0915\u093e\u0928\u0947 \u0915\u0940 \u092a\u0942\u0930\u0940 \u0915\u094b\u0936\u093f\u0936 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902\u0964",benefit:"\u091a\u092f\u0928\u093e\u0924\u094d\u092e\u0915 \u0927\u094d\u092f\u093e\u0928 (selective attention) \u0914\u0930 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0928\u093f\u092f\u0902\u0924\u094d\u0930\u0923 (response inhibition) \u2014 \u092f\u093e\u0928\u0940 \u0915\u093f\u0938\u0940 \u0932\u0915\u094d\u0937\u094d\u092f \u092a\u0930 \u0927\u094d\u092f\u093e\u0928 \u091f\u093f\u0915\u093e\u090f \u0930\u0916\u0928\u093e \u0914\u0930 \u0920\u0940\u0915 \u0909\u0938\u0915\u0947 \u092c\u0917\u0932 \u092e\u0947\u0902 \u092e\u094c\u091c\u0942\u0926 \u0927\u094d\u092f\u093e\u0928 \u092d\u091f\u0915\u093e\u0928\u0947 \u0935\u093e\u0932\u0940 \u091a\u0940\u091c\u093c\u094b\u0902 \u0915\u0947 \u0926\u0916\u093c\u0932 \u0915\u094b \u0926\u092c\u093e\u0928\u093e\u0964",history:"\u0907\u0938\u0947 1974 \u092e\u0947\u0902 \u092a\u0947\u0936 \u0915\u093f\u092f\u093e \u0917\u092f\u093e \u0914\u0930 \u092f\u0939 \u0927\u094d\u092f\u093e\u0928 \u0924\u0925\u093e \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u092a\u094d\u0930\u0924\u093f\u0938\u094d\u092a\u0930\u094d\u0927\u093e \u0915\u0947 \u0905\u0927\u094d\u092f\u092f\u0928 \u0915\u0947 \u0932\u093f\u090f \u0938\u0902\u091c\u094d\u091e\u093e\u0928\u093e\u0924\u094d\u092e\u0915 \u092e\u0928\u094b\u0935\u093f\u091c\u094d\u091e\u093e\u0928 \u0915\u0947 \u0938\u092c\u0938\u0947 \u0905\u0939\u092e \u0915\u093e\u0930\u094d\u092f\u094b\u0902 \u092e\u0947\u0902 \u0938\u0947 \u090f\u0915 \u092c\u0928 \u0917\u092f\u093e; \u0906\u091c \u092f\u0939 \u0906\u0927\u0941\u0928\u093f\u0915 attention-network \u092a\u0930\u0940\u0915\u094d\u0937\u0923 \u0915\u093e \u090f\u0915 \u092e\u0942\u0932 \u0939\u093f\u0938\u094d\u0938\u093e \u0939\u0948\u0964",creator:"Barbara \u0914\u0930 Charles Eriksen, \u091c\u093f\u0928\u094d\u0939\u094b\u0902\u0928\u0947 1974 \u092e\u0947\u0902 \u092b\u093c\u094d\u0932\u0948\u0902\u0915\u0930 \u091f\u093e\u0938\u094d\u0915 \u092a\u094d\u0930\u0915\u093e\u0936\u093f\u0924 \u0915\u093f\u092f\u093e (Perception & Psychophysics)\u0964",methods:"\u0928\u091c\u093c\u0930 \u0915\u094b \u092c\u0940\u091a \u0935\u093e\u0932\u0947 \u0924\u0940\u0930 \u092a\u0930 \u091c\u092e\u093e\u090f \u0930\u0916\u0947\u0902 \u0914\u0930 \u092c\u0917\u0932 \u0935\u093e\u0932\u0947 \u0924\u0940\u0930\u094b\u0902 \u0915\u094b \u092e\u0939\u091c\u093c \u0936\u094b\u0930 \u0938\u092e\u091d\u0947\u0902\u0964 \u0905\u092a\u0928\u0947 congruency effect \u092a\u0930 \u0928\u091c\u093c\u0930 \u0930\u0916\u0947\u0902 \u2014 \u092f\u093e\u0928\u0940 incongruent \u091f\u094d\u0930\u093e\u092f\u0932\u094b\u0902 \u092e\u0947\u0902 \u0932\u0917\u0928\u0947 \u0935\u093e\u0932\u093e \u0905\u0924\u093f\u0930\u093f\u0915\u094d\u0924 \u0938\u092e\u092f \u2014 \u0914\u0930 \u0915\u094b\u0936\u093f\u0936 \u0915\u0930\u0947\u0902 \u0915\u093f \u0938\u091f\u0940\u0915\u0924\u093e \u0918\u091f\u093e\u090f \u092c\u093f\u0928\u093e \u0907\u0938 \u0905\u0902\u0924\u0930 \u0915\u094b \u0915\u092e \u0915\u0930\u0924\u0947 \u091c\u093e\u090f\u0901\u0964",duration:"\u091b\u094b\u091f\u0947-\u091b\u094b\u091f\u0947 \u092c\u094d\u0932\u0949\u0915, \u090f\u0915 \u092c\u093e\u0930 \u092e\u0947\u0902 \u092c\u0938 \u0915\u0941\u091b \u092e\u093f\u0928\u091f\u0964 \u0936\u0941\u0930\u0941\u0906\u0924 \u092e\u0947\u0902 \u0906\u092a\u0915\u093e congruency cost \u0924\u0947\u091c\u093c\u0940 \u0938\u0947 \u0918\u091f\u0947\u0917\u093e \u0914\u0930 \u092b\u093f\u0930 \u090f\u0915 \u091c\u0917\u0939 \u0906\u0915\u0930 \u0938\u094d\u0925\u093f\u0930 \u0939\u094b \u091c\u093e\u090f\u0917\u093e\u0964",research:"\u092f\u0939 \u090f\u0915 \u092e\u091c\u093c\u092c\u0942\u0924 \u0914\u0930 \u092c\u093e\u0930-\u092c\u093e\u0930 \u0926\u094b\u0939\u0930\u093e\u092f\u093e \u091c\u093e \u091a\u0941\u0915\u093e \u092a\u094d\u0930\u092d\u093e\u0935 \u0939\u0948\u0964 \u0905\u092d\u094d\u092f\u093e\u0938 \u0938\u0947 \u0907\u0938\u0940 \u091f\u093e\u0938\u094d\u0915 \u092a\u0930 \u0906\u092a\u0915\u093e \u0926\u0916\u093c\u0932 (interference) \u0918\u091f\u0924\u093e \u0939\u0948; \u092a\u0930 \u092c\u093e\u0915\u093c\u0940 \u0915\u0949\u0928\u094d\u092b\u093c\u094d\u0932\u093f\u0915\u094d\u091f \u091f\u093e\u0938\u094d\u0915\u094b\u0902 \u0915\u0940 \u0924\u0930\u0939, \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0947 \u0927\u094d\u092f\u093e\u0928 \u0924\u0915 \u0907\u0938\u0915\u0947 \u0935\u094d\u092f\u093e\u092a\u0915 \u0938\u094d\u0925\u093e\u0928\u093e\u0902\u0924\u0930\u0923 \u0915\u0947 \u0938\u092c\u0942\u0924 \u0938\u0940\u092e\u093f\u0924 \u0939\u0948\u0902 \u2014 \u0907\u0938\u0932\u093f\u090f \u0907\u0938\u0947 \u090f\u0915 \u0916\u093c\u093e\u0938 \u0915\u094c\u0936\u0932 \u0915\u0947 \u0932\u093f\u090f \u0939\u0940 \u0938\u093e\u0927\u0947\u0902\u0964",rec:"\u0907\u0938\u0915\u093e \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0938\u0902\u0915\u0930\u0947, \u0927\u094d\u092f\u093e\u0928-\u092d\u091f\u0915\u093e\u0935-\u0930\u094b\u0927\u0940 \u092b\u093c\u094b\u0915\u0938 \u0915\u0947 \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0947 \u0932\u093f\u090f \u0915\u0930\u0947\u0902\u0964 \u0938\u091f\u0940\u0915\u0924\u093e \u090a\u0901\u091a\u0940 \u0930\u0916\u0947\u0902; \u092e\u0915\u093c\u0938\u0926 \u092c\u0917\u0932 \u0935\u093e\u0932\u0947 \u0924\u0940\u0930\u094b\u0902 \u0915\u093e \u0926\u0916\u093c\u0932 \u091d\u0947\u0932\u0928\u093e \u0939\u0948, \u0905\u0902\u0927\u093e\u0927\u0941\u0902\u0927 \u0930\u092b\u093c\u094d\u0924\u093e\u0930 \u0928\u0939\u0940\u0902\u0964",faq:[["\u092b\u093c\u094d\u0932\u0948\u0902\u0915\u0930 \u0907\u092b\u093c\u0947\u0915\u094d\u091f \u0915\u094d\u092f\u093e \u0939\u0948?","\u091c\u092c \u0906\u0938\u092a\u093e\u0938 \u0915\u0947 \u0924\u0940\u0930 \u092c\u0940\u091a \u0935\u093e\u0932\u0947 \u0932\u0915\u094d\u0937\u094d\u092f \u0938\u0947 \u0909\u0932\u091f\u0940 \u0926\u093f\u0936\u093e \u092e\u0947\u0902 \u0907\u0936\u093e\u0930\u093e \u0915\u0930\u0924\u0947 \u0939\u0948\u0902, \u0924\u092c \u0906\u092a \u0927\u0940\u092e\u0947 \u0914\u0930 \u0915\u092e \u0938\u091f\u0940\u0915 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902\u0964"],["\u092f\u0939 \u0915\u093f\u0938 \u091a\u0940\u091c\u093c \u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0930\u093e\u0924\u093e \u0939\u0948?","\u091a\u092f\u0928\u093e\u0924\u094d\u092e\u0915 \u0927\u094d\u092f\u093e\u0928 \u0914\u0930 \u0906\u0938\u092a\u093e\u0938 \u092e\u094c\u091c\u0942\u0926 \u0927\u094d\u092f\u093e\u0928-\u092d\u091f\u0915\u093e\u0928\u0947 \u0935\u093e\u0932\u0940 \u091a\u0940\u091c\u093c\u094b\u0902 \u0915\u094b \u0926\u092c\u093e\u0928\u0947 \u0915\u0940 \u0915\u094d\u0937\u092e\u0924\u093e\u0964"],["\u0924\u0940\u0930 \u092f\u093e \u0905\u0915\u094d\u0937\u0930?","\u0926\u094b\u0928\u094b\u0902 \u092e\u094c\u091c\u0942\u0926 \u0939\u0948\u0902 \u2014 \u092e\u0942\u0932 \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u092e\u0947\u0902 \u0905\u0915\u094d\u0937\u0930\u094b\u0902 \u0915\u093e \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0939\u094b\u0924\u093e \u0925\u093e; \u0924\u0940\u0930 \u0907\u0938\u0915\u093e \u0906\u092e \u0906\u0927\u0941\u0928\u093f\u0915 \u0930\u0942\u092a \u0939\u0948\u0964"]],variants:"\u0924\u0940\u0930, \u0905\u0915\u094d\u0937\u0930 \u0914\u0930 \u0930\u0902\u0917 \u0935\u093e\u0932\u0947 \u092b\u093c\u094d\u0932\u0948\u0902\u0915\u0930; \u092c\u0917\u0932 \u0935\u093e\u0932\u0947 \u0924\u0940\u0930\u094b\u0902 \u0915\u0940 \u0926\u0942\u0930\u0940 \u092c\u0926\u0932\u0928\u093e; \u0914\u0930 attention-network \u091f\u0947\u0938\u094d\u091f \u091c\u0948\u0938\u0940 \u092e\u093f\u0932\u0940-\u091c\u0941\u0932\u0940 \u0915\u0949\u0928\u094d\u092b\u093c\u094d\u0932\u093f\u0915\u094d\u091f \u092c\u0948\u091f\u0930\u093f\u092f\u093e\u0901\u0964"},zh:{about:"\u4e00\u4e2a\u5c45\u4e2d\u7684\u7bad\u5934\u88ab\u4e24\u4fa7\u7684\u7bad\u5934\u5305\u56f4\uff0c\u5b83\u4eec\u8981\u4e48\u6307\u5411\u540c\u4e00\u65b9\u5411\uff08\u4e00\u81f4\uff09\uff0c\u8981\u4e48\u6307\u5411\u76f8\u53cd\u65b9\u5411\uff08\u4e0d\u4e00\u81f4\uff09\u3002\u4f60\u53ea\u5bf9\u4e2d\u95f4\u90a3\u4e2a\u7bad\u5934\u4f5c\u51fa\u53cd\u5e94\u2014\u2014\u800c\u5f53\u4e24\u4fa7\u7bad\u5934\u4e0e\u5b83\u5531\u53cd\u8c03\u65f6\uff0c\u5c31\u4f1a\u8ddf\u4f60\u8f83\u52b2\u3002",benefit:"\u9009\u62e9\u6027\u6ce8\u610f\u548c\u53cd\u5e94\u6291\u5236\u2014\u2014\u5728\u4e13\u6ce8\u4e8e\u4e00\u4e2a\u76ee\u6807\u7684\u540c\u65f6\uff0c\u538b\u5236\u7d27\u6328\u7740\u5b83\u7684\u5e72\u6270\u7269\u6240\u5e26\u6765\u7684\u5e72\u6270\u3002",history:"\u5b83\u4e8e 1974 \u5e74\u63d0\u51fa\uff0c\u6210\u4e3a\u8ba4\u77e5\u5fc3\u7406\u5b66\u4e2d\u7814\u7a76\u6ce8\u610f\u548c\u53cd\u5e94\u7ade\u4e89\u6700\u91cd\u8981\u7684\u4efb\u52a1\u4e4b\u4e00\uff0c\u4e5f\u662f\u73b0\u4ee3\u6ce8\u610f\u7f51\u7edc\u6d4b\u9a8c\u7684\u6838\u5fc3\u7ec4\u6210\u90e8\u5206\u3002",creator:"Barbara \u548c Charles Eriksen\uff0c\u4ed6\u4eec\u4e8e 1974 \u5e74\u53d1\u8868\u4e86 flanker \u4efb\u52a1\uff08\u300aPerception & Psychophysics\u300b\uff09\u3002",methods:"\u9501\u5b9a\u4e2d\u95f4\uff0c\u628a\u4e24\u4fa7\u7bad\u5934\u5f53\u4f5c\u566a\u58f0\u3002\u7559\u610f\u4f60\u7684\u4e00\u81f4\u6027\u6548\u5e94\u2014\u2014\u4e5f\u5c31\u662f\u4e0d\u4e00\u81f4\u8bd5\u6b21\u4e0a\u591a\u82b1\u7684\u65f6\u95f4\u2014\u2014\u5e76\u8bbe\u6cd5\u5728\u4e0d\u727a\u7272\u51c6\u786e\u7387\u7684\u524d\u63d0\u4e0b\u628a\u5b83\u7f29\u5c0f\u3002",duration:"\u77ed\u65f6\u6bb5\uff0c\u6bcf\u6b21\u51e0\u5206\u949f\u3002\u4f60\u7684\u4e00\u81f4\u6027\u4ee3\u4ef7\u4f1a\u5728\u65e9\u671f\u4e0b\u964d\uff0c\u7136\u540e\u8d8b\u4e8e\u7a33\u5b9a\u3002",research:"\u4e00\u4e2a\u7a33\u5065\u3001\u88ab\u5927\u91cf\u91cd\u590d\u9a8c\u8bc1\u7684\u6548\u5e94\u3002\u8bad\u7ec3\u4f1a\u964d\u4f4e\u4f60\u5728\u8fd9\u9879\u4efb\u52a1\u672c\u8eab\u4e0a\u7684\u5e72\u6270\uff1b\u548c\u5176\u4ed6\u51b2\u7a81\u4efb\u52a1\u4e00\u6837\uff0c\u5173\u4e8e\u5b83\u80fd\u5e7f\u6cdb\u8fc1\u79fb\u5230\u65e5\u5e38\u4e13\u6ce8\u529b\u7684\u8bc1\u636e\u5f88\u6709\u9650\u2014\u2014\u7ec3\u5b83\u662f\u4e3a\u4e86\u8fd9\u9879\u5177\u4f53\u6280\u80fd\u3002",rec:"\u7528\u5b83\u6765\u7ec3\u4e60\u72ed\u7a84\u7684\u3001\u6297\u5e72\u6270\u7684\u4e13\u6ce8\u3002\u4fdd\u6301\u9ad8\u51c6\u786e\u7387\uff1b\u76ee\u6807\u662f\u62b5\u6297\u4e24\u4fa7\u7bad\u5934\uff0c\u800c\u4e0d\u662f\u76f2\u76ee\u6c42\u5feb\u3002",faq:[["\u4ec0\u4e48\u662f flanker \u6548\u5e94\uff1f","\u5f53\u5468\u56f4\u7684\u7bad\u5934\u4e0e\u4e2d\u592e\u76ee\u6807\u6307\u5411\u76f8\u53cd\u65f6\uff0c\u4f60\u4f1a\u66f4\u6162\u3001\u4e5f\u66f4\u4e0d\u51c6\u786e\u3002"],["\u5b83\u8bad\u7ec3\u4ec0\u4e48\uff1f","\u9009\u62e9\u6027\u6ce8\u610f\uff0c\u4ee5\u53ca\u6291\u5236\u90bb\u8fd1\u5e72\u6270\u7269\u7684\u80fd\u529b\u3002"],["\u7528\u7bad\u5934\u8fd8\u662f\u5b57\u6bcd\uff1f","\u4e24\u8005\u90fd\u6709\u2014\u2014\u7ecf\u5178\u7248\u672c\u7528\u7684\u662f\u5b57\u6bcd\uff1b\u7bad\u5934\u662f\u5e38\u89c1\u7684\u73b0\u4ee3\u5f62\u5f0f\u3002"]],variants:"\u7bad\u5934\u3001\u5b57\u6bcd\u548c\u989c\u8272 flanker\uff1b\u6539\u53d8\u4e24\u4fa7\u5e72\u6270\u7269\u7684\u8ddd\u79bb\uff1b\u4ee5\u53ca\u50cf\u6ce8\u610f\u7f51\u7edc\u6d4b\u9a8c\u8fd9\u6837\u628a\u51b2\u7a81\u7ec4\u5408\u8d77\u6765\u7684\u6210\u5957\u6d4b\u9a8c\u3002"}},"go-no-go":{ru:{about:"\u041d\u0430 \u044d\u043a\u0440\u0430\u043d\u0435 \u043f\u043e \u043e\u0434\u043d\u043e\u043c\u0443 \u0432\u0441\u043f\u044b\u0445\u0438\u0432\u0430\u044e\u0442 \u0441\u0438\u0433\u043d\u0430\u043b\u044b, \u0438 \u0431\u043e\u043b\u044c\u0448\u0438\u043d\u0441\u0442\u0432\u043e \u0438\u0437 \u043d\u0438\u0445 \u2014 \xab\u0436\u043c\u0438\xbb: \u043d\u0430 \u043d\u0438\u0445 \u043d\u0443\u0436\u043d\u043e \u043a\u0430\u043a \u043c\u043e\u0436\u043d\u043e \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u043d\u0430\u0436\u0430\u0442\u044c. \u041d\u043e \u0438\u0437\u0440\u0435\u0434\u043a\u0430 \u043f\u043e\u044f\u0432\u043b\u044f\u0435\u0442\u0441\u044f \u0441\u0438\u0433\u043d\u0430\u043b \xab\u043d\u0435 \u0436\u043c\u0438\xbb, \u0438 \u043d\u0430 \u043d\u0451\u043c \u043d\u0435\u043b\u044c\u0437\u044f \u0434\u0435\u043b\u0430\u0442\u044c \u043d\u0438\u0447\u0435\u0433\u043e. \u0412\u0441\u044f \u0441\u043e\u043b\u044c \u0432 \u0442\u043e\u043c, \u0447\u0442\u043e \u043d\u0430\u0436\u0430\u0442\u0438\u0435 \u0437\u0430 \u043f\u0430\u0440\u0443 \u0441\u0435\u043a\u0443\u043d\u0434 \u043f\u0440\u0435\u0432\u0440\u0430\u0449\u0430\u0435\u0442\u0441\u044f \u0432 \u043f\u0440\u0438\u0432\u044b\u0447\u043a\u0443, \u0438 \u0443\u0434\u0435\u0440\u0436\u0430\u0442\u044c \u043f\u0430\u043b\u0435\u0446 \u043d\u0430 \u0437\u0430\u043f\u0440\u0435\u0442\u043d\u043e\u043c \u0441\u0438\u0433\u043d\u0430\u043b\u0435 \u043e\u043a\u0430\u0437\u044b\u0432\u0430\u0435\u0442\u0441\u044f \u043f\u043e-\u043d\u0430\u0441\u0442\u043e\u044f\u0449\u0435\u043c\u0443 \u0442\u0440\u0443\u0434\u043d\u043e.",benefit:"\u0422\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442\u0441\u044f \u0442\u043e\u0440\u043c\u043e\u0436\u0435\u043d\u0438\u0435 \u0440\u0435\u0430\u043a\u0446\u0438\u0438 \u2014 \u0443\u043c\u0435\u043d\u0438\u0435 \u043e\u0442\u043c\u0435\u043d\u0438\u0442\u044c \u0443\u0436\u0435 \u043f\u043e\u0447\u0442\u0438 \u0437\u0430\u043f\u0443\u0449\u0435\u043d\u043d\u043e\u0435 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435, \u0430 \u0432\u043c\u0435\u0441\u0442\u0435 \u0441 \u043d\u0438\u043c \u0438 \u0443\u0441\u0442\u043e\u0439\u0447\u0438\u0432\u043e\u0435 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435, \u0431\u0435\u0437 \u043a\u043e\u0442\u043e\u0440\u043e\u0433\u043e \u043d\u0435 \u0443\u0441\u043b\u0435\u0434\u0438\u0442\u044c \u0437\u0430 \u0440\u0435\u0434\u043a\u0438\u043c \u0441\u0438\u0433\u043d\u0430\u043b\u043e\u043c \xab\u0441\u0442\u043e\u043f\xbb. \u0415\u0441\u043b\u0438 \u043f\u0440\u043e\u0449\u0435, \u044d\u0442\u043e \u043f\u0435\u0434\u0430\u043b\u044c \u0442\u043e\u0440\u043c\u043e\u0437\u0430 \u0441\u0430\u043c\u043e\u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044f, \u0430 \u043d\u0435 \u0433\u0430\u0437\u0430.",history:"\u0421\u0445\u0435\u043c\u0430 \xab\u0436\u043c\u0438 / \u043d\u0435 \u0436\u043c\u0438\xbb \u0432\u043e\u0441\u0445\u043e\u0434\u0438\u0442 \u043a \u0424\u0440\u0430\u043d\u0446\u0438\u0441\u043a\u0443 \u0414\u043e\u043d\u0434\u0435\u0440\u0441\u0443: \u0432 1868 \u0433\u043e\u0434\u0443 \u043e\u043d \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u043b \u0435\u0451 \u043a\u0430\u043a \u043e\u0434\u043d\u0443 \u0438\u0437 \u0442\u0440\u0451\u0445 \u0437\u0430\u0434\u0430\u0447 \u0432 \u0441\u0432\u043e\u0451\u043c \u043c\u0435\u0442\u043e\u0434\u0435 \u0432\u044b\u0447\u0438\u0442\u0430\u043d\u0438\u044f \u0434\u043b\u044f \u0438\u0437\u043c\u0435\u0440\u0435\u043d\u0438\u044f \u0432\u0440\u0435\u043c\u0435\u043d\u0438 \u043f\u0441\u0438\u0445\u0438\u0447\u0435\u0441\u043a\u0438\u0445 \u043f\u0440\u043e\u0446\u0435\u0441\u0441\u043e\u0432. \u0417\u0430 XX \u0432\u0435\u043a \u043f\u0440\u0438\u0451\u043c \u0441\u0442\u0430\u043b \u0432 \u044d\u043a\u0441\u043f\u0435\u0440\u0438\u043c\u0435\u043d\u0442\u0430\u043b\u044c\u043d\u043e\u0439 \u0438 \u043a\u043b\u0438\u043d\u0438\u0447\u0435\u0441\u043a\u043e\u0439 \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u0438 \u0441\u0442\u0430\u043d\u0434\u0430\u0440\u0442\u043d\u044b\u043c \u0441\u043f\u043e\u0441\u043e\u0431\u043e\u043c \u043e\u0446\u0435\u043d\u0438\u0432\u0430\u0442\u044c \u0438\u043c\u043f\u0443\u043b\u044c\u0441\u0438\u0432\u043d\u043e\u0441\u0442\u044c \u0438 \u0440\u0430\u0431\u043e\u0442\u0443 \u043b\u043e\u0431\u043d\u044b\u0445 \u0434\u043e\u043b\u0435\u0439, \u0430 \u043f\u043e\u0437\u0436\u0435 \u0440\u0430\u0437\u043e\u0448\u0451\u043b\u0441\u044f \u043f\u043e \u043d\u0435\u0439\u0440\u043e\u0432\u0438\u0437\u0443\u0430\u043b\u0438\u0437\u0430\u0446\u0438\u0438, \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u044f\u043c \u0421\u0414\u0412\u0413 \u0438 \u0437\u0430\u0432\u0438\u0441\u0438\u043c\u043e\u0441\u0442\u0435\u0439 \u0438 \u043f\u0440\u0438\u043b\u043e\u0436\u0435\u043d\u0438\u044f\u043c \u0434\u043b\u044f \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0438 \u043c\u043e\u0437\u0433\u0430.",creator:"\u0415\u0434\u0438\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0433\u043e \u0430\u0432\u0442\u043e\u0440\u0430 \u043d\u0435\u0442. \u041e\u0431\u044b\u0447\u043d\u043e \u043f\u0440\u0438\u0451\u043c \u0432\u043e\u0437\u0432\u043e\u0434\u044f\u0442 \u043a \u043d\u0438\u0434\u0435\u0440\u043b\u0430\u043d\u0434\u0441\u043a\u043e\u043c\u0443 \u0444\u0438\u0437\u0438\u043e\u043b\u043e\u0433\u0443 \u0424\u0440\u0430\u043d\u0446\u0438\u0441\u043a\u0443 \u041a\u043e\u0440\u043d\u0435\u043b\u0438\u0441\u0443 \u0414\u043e\u043d\u0434\u0435\u0440\u0441\u0443 \u0438 \u0435\u0433\u043e \u0440\u0430\u0431\u043e\u0442\u0435 \u043e \u0432\u0440\u0435\u043c\u0435\u043d\u0438 \u0440\u0435\u0430\u043a\u0446\u0438\u0438 1868 \u0433\u043e\u0434\u0430 (\u0435\u0433\u043e \xabC-\u0437\u0430\u0434\u0430\u0447\u0430\xbb), \u0430 \u0434\u043e\u0440\u0430\u0431\u0430\u0442\u044b\u0432\u0430\u043b\u0438 \u0441\u0445\u0435\u043c\u0443 \u0443\u0436\u0435 \u043c\u043d\u043e\u0433\u0438\u0435 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u0438. \u041e\u043d\u0430 \u043f\u0440\u0438\u043d\u0430\u0434\u043b\u0435\u0436\u0438\u0442 \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u0438 \u043c\u0435\u043d\u0442\u0430\u043b\u044c\u043d\u043e\u0439 \u0445\u0440\u043e\u043d\u043e\u043c\u0435\u0442\u0440\u0438\u0438 \u0432 \u044d\u043a\u0441\u043f\u0435\u0440\u0438\u043c\u0435\u043d\u0442\u0430\u043b\u044c\u043d\u043e\u0439 \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u0438, \u0430 \u043d\u0435 \u043a\u0430\u043a\u043e\u043c\u0443-\u0442\u043e \u043e\u0434\u043d\u043e\u043c\u0443 \u0438\u043c\u0435\u043d\u0438 \u0438 \u0433\u043e\u0434\u0443.",methods:"\u0414\u0435\u0440\u0436\u0438\u0442\u0435 \u0441\u0438\u0433\u043d\u0430\u043b \xab\u043d\u0435 \u0436\u043c\u0438\xbb \u043f\u043e-\u043d\u0430\u0441\u0442\u043e\u044f\u0449\u0435\u043c\u0443 \u0440\u0435\u0434\u043a\u0438\u043c \u2014 \u043f\u0440\u0438\u043c\u0435\u0440\u043d\u043e \u043e\u0434\u0438\u043d \u0438\u0437 \u0447\u0435\u0442\u044b\u0440\u0451\u0445 \u0438\u043b\u0438 \u0440\u0435\u0436\u0435: \u0438\u043c\u0435\u043d\u043d\u043e \u044d\u0442\u043e \u0441\u043e\u0437\u0434\u0430\u0451\u0442 \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u0438\u0439 \u043f\u043e\u0440\u044b\u0432, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u0432\u044b \u0438 \u0443\u0447\u0438\u0442\u0435\u0441\u044c \u0433\u0430\u0441\u0438\u0442\u044c. \u0411\u0435\u0440\u0438\u0442\u0435 \u0442\u0435\u043c\u043f \u0431\u043e\u0434\u0440\u044b\u0439, \u043d\u043e \u0431\u0435\u0437 \u043d\u0430\u0434\u0440\u044b\u0432\u0430, \u0438 \u0441\u0447\u0438\u0442\u0430\u0439\u0442\u0435 \u043f\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u0435\u043c \u043d\u0435 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c, \u0430 \u043b\u043e\u0436\u043d\u044b\u0435 \u0441\u0440\u0430\u0431\u0430\u0442\u044b\u0432\u0430\u043d\u0438\u044f (\u043d\u0430\u0436\u0430\u0442\u0438\u044f \u043d\u0430 \u0437\u0430\u043f\u0440\u0435\u0442\u043d\u044b\u0439 \u0441\u0438\u0433\u043d\u0430\u043b). \u0415\u0441\u043b\u0438 \u043e\u0448\u0438\u0431\u043e\u043a \u043d\u0435\u0442 \u0441\u043e\u0432\u0441\u0435\u043c \u2014 \u0432\u044b \u0438\u0434\u0451\u0442\u0435 \u0441\u043b\u0438\u0448\u043a\u043e\u043c \u043c\u0435\u0434\u043b\u0435\u043d\u043d\u043e; \u0443\u0441\u043a\u043e\u0440\u044f\u0439\u0442\u0435\u0441\u044c, \u043f\u043e\u043a\u0430 \u043f\u0440\u043e\u043c\u0430\u0445\u0438 \u043d\u0435 \u043d\u0430\u0447\u043d\u0443\u0442 \u043f\u0440\u043e\u0441\u043a\u0430\u043a\u0438\u0432\u0430\u0442\u044c, \u0438 \u0434\u0435\u0440\u0436\u0438\u0442\u0435\u0441\u044c \u043d\u0430 \u044d\u0442\u043e\u0439 \u0433\u0440\u0430\u043d\u0438.",duration:"\u041a\u043e\u0440\u043e\u0442\u043a\u043e \u0438 \u0447\u0430\u0441\u0442\u043e \u043b\u0443\u0447\u0448\u0435, \u0447\u0435\u043c \u0434\u043e\u043b\u0433\u043e \u0438 \u0440\u0435\u0434\u043a\u043e. \u041f\u044f\u0442\u0438-\u0434\u0435\u0441\u044f\u0442\u0438 \u043c\u0438\u043d\u0443\u0442 \u0437\u0430 \u043f\u043e\u0434\u0445\u043e\u0434 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0440\u0430\u0437 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e \u0434\u043e\u0441\u0442\u0430\u0442\u043e\u0447\u043d\u043e: \u0437\u0430\u0434\u0430\u0447\u0430 \u0443\u0442\u043e\u043c\u043b\u044f\u0435\u0442, \u0438 \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u044c \u043f\u0430\u0434\u0430\u0435\u0442, \u043a\u0430\u043a \u0442\u043e\u043b\u044c\u043a\u043e \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u0443\u043f\u043b\u044b\u0432\u0430\u0435\u0442, \u2014 \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u043e\u0441\u0442\u0430\u043d\u0430\u0432\u043b\u0438\u0432\u0430\u0439\u0442\u0435\u0441\u044c, \u043f\u043e\u043a\u0430 \u0432\u044b \u0435\u0449\u0451 \u0441\u043e\u0431\u0440\u0430\u043d\u043d\u044b, \u0430 \u043d\u0435 \u0432\u044b\u043c\u0443\u0447\u0438\u0432\u0430\u0439\u0442\u0435 \u0434\u043b\u0438\u043d\u043d\u044b\u0439 \u0431\u043b\u043e\u043a.",research:"\u0422\u0432\u0451\u0440\u0434\u043e \u0434\u043e\u043a\u0430\u0437\u0430\u043d\u043e \u043d\u0435\u043c\u043d\u043e\u0433\u043e\u0435: \u0441 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u043e\u0439 \u0432\u044b \u0440\u0435\u0436\u0435 \u043f\u0440\u043e\u043c\u0430\u0445\u0438\u0432\u0430\u0435\u0442\u0435\u0441\u044c \u0438 \u0442\u043e\u0440\u043c\u043e\u0437\u0438\u0442\u0435 \u0432 \u044d\u0442\u043e\u0439 \u0437\u0430\u0434\u0430\u0447\u0435 \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u0438 \u0447\u0438\u0449\u0435. \u0421 \u0448\u0438\u0440\u043e\u043a\u0438\u043c\u0438 \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f\u043c\u0438 \u0432\u0441\u0451 \u043a\u0443\u0434\u0430 \u0445\u0443\u0436\u0435. \u0418\u0437\u0432\u0435\u0441\u0442\u043d\u043e\u0435 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u0435 \u042d\u043d\u0433\u0435 \u0441 \u043a\u043e\u043b\u043b\u0435\u0433\u0430\u043c\u0438 (2014) \u043d\u0435 \u043d\u0430\u0448\u043b\u043e \u0443\u0431\u0435\u0434\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0445 \u0441\u0432\u0438\u0434\u0435\u0442\u0435\u043b\u044c\u0441\u0442\u0432, \u0447\u0442\u043e \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0430 \u0442\u043e\u0440\u043c\u043e\u0436\u0435\u043d\u0438\u044f \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0438\u0442\u0441\u044f \u043d\u0430 \u043d\u0435\u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u044b\u0435 \u0441\u043f\u043e\u0441\u043e\u0431\u043d\u043e\u0441\u0442\u0438, \u0430 \u043e\u0431\u0437\u043e\u0440\u044b \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0438 \u0443\u043f\u0440\u0430\u0432\u043b\u044f\u044e\u0449\u0438\u0445 \u0444\u0443\u043d\u043a\u0446\u0438\u0439 \u0432 \u0446\u0435\u043b\u043e\u043c \u043f\u043e\u043a\u0430\u0437\u044b\u0432\u0430\u044e\u0442 \u0441\u043b\u0430\u0431\u044b\u0439 \u0434\u0430\u043b\u044c\u043d\u0438\u0439 \u043f\u0435\u0440\u0435\u043d\u043e\u0441 \u0438 \u043e\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0435 \u043d\u0430\u0434\u0451\u0436\u043d\u043e\u0433\u043e \u043f\u0440\u0438\u0440\u043e\u0441\u0442\u0430 IQ. \u041f\u0438\u0449\u0435\u0432\u043e\u0439 \u0432\u0430\u0440\u0438\u0430\u043d\u0442 \xab\u0436\u043c\u0438 / \u043d\u0435 \u0436\u043c\u0438\xbb \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043b\u044c\u043d\u043e \u0441\u0442\u0430\u0431\u0438\u043b\u044c\u043d\u043e \u0441\u043d\u0438\u0436\u0430\u0435\u0442 \u043f\u0440\u0438\u0432\u043b\u0435\u043a\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c \xab\u0437\u0430\u043f\u0440\u0435\u0442\u043d\u044b\u0445\xbb \u043f\u0440\u043e\u0434\u0443\u043a\u0442\u043e\u0432 \u0432 \u043b\u0430\u0431\u043e\u0440\u0430\u0442\u043e\u0440\u0438\u0438, \u043d\u043e \u043c\u0435\u043d\u044f\u0435\u0442 \u043b\u0438 \u044d\u0442\u043e \u0440\u0435\u0430\u043b\u044c\u043d\u043e\u0435 \u043f\u0435\u0440\u0435\u0435\u0434\u0430\u043d\u0438\u0435 \u0438\u043b\u0438 \u0432\u044b\u043f\u0438\u0432\u043a\u0443 \u043d\u0430\u0434\u043e\u043b\u0433\u043e \u2014 \u043f\u043e\u043a\u0430 \u0441\u043f\u043e\u0440\u043d\u043e, \u0442\u0430\u043a \u0447\u0442\u043e \u043a \u043b\u044e\u0431\u044b\u043c \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f\u043c \u0441\u0432\u0435\u0440\u0445 \xab\u0432\u044b \u0441\u0442\u0430\u043d\u0435\u0442\u0435 \u043b\u0443\u0447\u0448\u0435 \u0432 \u0441\u0430\u043c\u043e\u0439 \u0437\u0430\u0434\u0430\u0447\u0435\xbb \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u0435\u0441\u044c \u043e\u0441\u0442\u043e\u0440\u043e\u0436\u043d\u043e.",rec:"\u0413\u043e\u043d\u0438\u0442\u0435\u0441\u044c \u0437\u0430 \u043d\u0438\u0437\u043a\u043e\u0439 \u0434\u043e\u043b\u0435\u0439 \u043b\u043e\u0436\u043d\u044b\u0445 \u0441\u0440\u0430\u0431\u0430\u0442\u044b\u0432\u0430\u043d\u0438\u0439, \u0430 \u043d\u0435 \u0437\u0430 \u0432\u0440\u0435\u043c\u0435\u043d\u0435\u043c \u0440\u0435\u0430\u043a\u0446\u0438\u0438: \u043f\u043e\u0434\u0445\u043e\u0434, \u0433\u0434\u0435 \u0432\u044b \u043e\u0441\u0442\u0430\u043b\u0438\u0441\u044c \u0442\u043e\u0447\u043d\u044b \u043d\u0430 \u0431\u043e\u0434\u0440\u043e\u043c \u0442\u0435\u043c\u043f\u0435, \u0446\u0435\u043d\u043d\u0435\u0435 \u0431\u044b\u0441\u0442\u0440\u043e\u0433\u043e, \u043d\u043e \u0443\u0441\u0435\u044f\u043d\u043d\u043e\u0433\u043e \u043f\u0440\u043e\u043c\u0430\u0445\u0430\u043c\u0438.",faq:[["\u042d\u0442\u043e \u0442\u043e \u0436\u0435 \u0441\u0430\u043c\u043e\u0435, \u0447\u0442\u043e \u0437\u0430\u0434\u0430\u0447\u0430 \u0441\u043e \u0441\u0442\u043e\u043f-\u0441\u0438\u0433\u043d\u0430\u043b\u043e\u043c?","\u041d\u0435\u0442. \u0412 \xab\u0436\u043c\u0438 / \u043d\u0435 \u0436\u043c\u0438\xbb \u0432\u044b \u0440\u0435\u0448\u0430\u0435\u0442\u0435 \u043f\u043e \u0441\u0430\u043c\u043e\u043c\u0443 \u0441\u0438\u0433\u043d\u0430\u043b\u0443, \u0434\u0435\u0439\u0441\u0442\u0432\u043e\u0432\u0430\u0442\u044c \u0438\u043b\u0438 \u043d\u0435\u0442, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u043c\u043e\u0436\u0435\u0442\u0435 \u0443\u0434\u0435\u0440\u0436\u0430\u0442\u044c\u0441\u044f \u0435\u0449\u0451 \u0434\u043e \u0434\u0432\u0438\u0436\u0435\u043d\u0438\u044f. \u0412 \u0437\u0430\u0434\u0430\u0447\u0435 \u0441\u043e \u0441\u0442\u043e\u043f-\u0441\u0438\u0433\u043d\u0430\u043b\u043e\u043c \u0441\u043d\u0430\u0447\u0430\u043b\u0430 \u0432\u0435\u043b\u044f\u0442 \u0436\u0430\u0442\u044c, \u0430 \u0441\u043f\u0443\u0441\u0442\u044f \u043c\u0433\u043d\u043e\u0432\u0435\u043d\u0438\u0435 \u0438\u043d\u043e\u0433\u0434\u0430 \u043a\u043e\u043c\u0430\u043d\u0434\u0443\u044e\u0442 \u043e\u0442\u043c\u0435\u043d\u0438\u0442\u044c \u2014 \u0438 \u044d\u0442\u043e \u0443\u0436\u0435 \u043e\u0442\u043c\u0435\u043d\u0430 \u0443\u0436\u0435 \u043d\u0430\u0447\u0430\u0442\u043e\u0433\u043e \u0434\u0432\u0438\u0436\u0435\u043d\u0438\u044f. \u041f\u0440\u0438\u0451\u043c\u044b \u0440\u043e\u0434\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0435, \u043d\u043e \u0437\u0430\u0434\u0435\u0439\u0441\u0442\u0432\u0443\u044e\u0442 \u0447\u0443\u0442\u044c \u0440\u0430\u0437\u043d\u044b\u0435 \u043c\u0435\u0445\u0430\u043d\u0438\u0437\u043c\u044b \u0442\u043e\u0440\u043c\u043e\u0436\u0435\u043d\u0438\u044f."],["\u0421\u0442\u0430\u043d\u0443 \u043b\u0438 \u044f \u043c\u0435\u043d\u0435\u0435 \u0438\u043c\u043f\u0443\u043b\u044c\u0441\u0438\u0432\u043d\u044b\u043c \u0432 \u0436\u0438\u0437\u043d\u0438, \u0435\u0441\u043b\u0438 \u0431\u0443\u0434\u0443 \u044d\u0442\u043e \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u0430\u0442\u044c?","\u0427\u0435\u0441\u0442\u043d\u043e \u2014 \u0434\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432 \u043c\u0430\u043b\u043e. \u0412\u044b \u0441\u0442\u0430\u0431\u0438\u043b\u044c\u043d\u043e \u0441\u0442\u0430\u043d\u0435\u0442\u0435 \u043b\u0443\u0447\u0448\u0435 \u0432 \u0441\u0430\u043c\u043e\u0439 \u0437\u0430\u0434\u0430\u0447\u0435 \u0438 \u0432 \u0443\u0434\u0435\u0440\u0436\u0430\u043d\u0438\u0438 \u0440\u0435\u0430\u043a\u0446\u0438\u0438 \u0432\u043d\u0443\u0442\u0440\u0438 \u043d\u0435\u0451, \u043d\u043e \u043f\u0435\u0440\u0435\u043d\u043e\u0441 \u043d\u0430 \u043f\u043e\u0432\u0441\u0435\u0434\u043d\u0435\u0432\u043d\u044b\u0439 \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044c \u043f\u043e\u0440\u044b\u0432\u043e\u0432 \u0438\u043b\u0438 \u043d\u0430 \u043e\u0431\u0449\u0443\u044e \u0434\u0438\u0441\u0446\u0438\u043f\u043b\u0438\u043d\u0443 \u0441\u043b\u0430\u0431 \u0438 \u0441\u043f\u043e\u0440\u0435\u043d. \u0418\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0439\u0442\u0435 \u044d\u0442\u043e \u043a\u0430\u043a \u0442\u043e\u0447\u0435\u0447\u043d\u0443\u044e \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0443 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f \u0438 \u0442\u043e\u0440\u043c\u043e\u0436\u0435\u043d\u0438\u044f, \u0430 \u043d\u0435 \u043a\u0430\u043a \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043e \u043e\u0442 \u0438\u043c\u043f\u0443\u043b\u044c\u0441\u0438\u0432\u043d\u043e\u0441\u0442\u0438."],["\u042f \u0432\u0441\u0451 \u0432\u0440\u0435\u043c\u044f \u0436\u043c\u0443 \u043d\u0430 \u0437\u0430\u043f\u0440\u0435\u0442\u043d\u044b\u0439 \u0441\u0438\u0433\u043d\u0430\u043b. \u042f \u0434\u0435\u043b\u0430\u044e \u0447\u0442\u043e-\u0442\u043e \u043d\u0435 \u0442\u0430\u043a?","\u0412\u043e\u0432\u0441\u0435 \u043d\u0435\u0442. \u042d\u0442\u0438 \u043f\u0440\u043e\u043c\u0430\u0445\u0438 (\u0438\u0445 \u043d\u0430\u0437\u044b\u0432\u0430\u044e\u0442 \u043e\u0448\u0438\u0431\u043a\u0430\u043c\u0438 \u043a\u043e\u043c\u0438\u0441\u0441\u0438\u0438) \u2014 \u0438 \u0435\u0441\u0442\u044c \u0441\u0443\u0442\u044c \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u044f \u0438 \u0433\u043b\u0430\u0432\u043d\u043e\u0435, \u0447\u0442\u043e \u043e\u043d\u043e \u0438\u0437\u043c\u0435\u0440\u044f\u0435\u0442. \u041d\u0430\u0432\u044b\u043a \u0432 \u0442\u043e\u043c, \u0447\u0442\u043e\u0431\u044b \u043f\u0440\u0438\u0442\u043e\u0440\u043c\u043e\u0437\u0438\u0442\u044c \u0440\u043e\u0432\u043d\u043e \u043d\u0430\u0441\u0442\u043e\u043b\u044c\u043a\u043e, \u0447\u0442\u043e\u0431\u044b \u0438\u0445 \u043b\u043e\u0432\u0438\u0442\u044c. \u0410 \u0435\u0441\u043b\u0438 \u043e\u0448\u0438\u0431\u043e\u043a \u043d\u043e\u043b\u044c \u2014 \u0432\u044b, \u0441\u043a\u043e\u0440\u0435\u0435 \u0432\u0441\u0435\u0433\u043e, \u0441\u043b\u0438\u0448\u043a\u043e\u043c \u043e\u0441\u0442\u043e\u0440\u043e\u0436\u043d\u0438\u0447\u0430\u0435\u0442\u0435, \u0438 \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043e\u0447\u043d\u043e\u0439 \u043f\u043e\u043b\u044c\u0437\u044b \u043f\u043e\u0447\u0442\u0438 \u043d\u0435\u0442."]],variants:"\u0412\u0435\u0440\u0441\u0438\u0438 \u0440\u0430\u0437\u043b\u0438\u0447\u0430\u044e\u0442\u0441\u044f \u0442\u0435\u043c, \u043d\u0430\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0440\u0435\u0434\u043e\u043a \u0437\u0430\u043f\u0440\u0435\u0442\u043d\u044b\u0439 \u0441\u0438\u0433\u043d\u0430\u043b \u0438 \u0447\u0442\u043e \u0438\u043c\u0435\u043d\u043d\u043e \u0441\u043b\u0443\u0436\u0438\u0442 \u0441\u0438\u0433\u043d\u0430\u043b\u0430\u043c\u0438. \u0412 \u0442\u0435\u0441\u0442\u0435 SART (\u0420\u043e\u0431\u0435\u0440\u0442\u0441\u043e\u043d, 1997) \u043f\u0440\u043e\u043f\u043e\u0440\u0446\u0438\u044e \u043f\u0435\u0440\u0435\u0432\u043e\u0440\u0430\u0447\u0438\u0432\u0430\u044e\u0442: \xab\u0436\u043c\u0438\xbb \u0438\u0434\u0451\u0442 \u043f\u043e\u0441\u0442\u043e\u044f\u043d\u043d\u043e, \u0430 \xab\u043d\u0435 \u0436\u043c\u0438\xbb \u0440\u0435\u0434\u043a\u043e, \u0438 \u0443\u043f\u043e\u0440 \u0441\u043c\u0435\u0449\u0430\u0435\u0442\u0441\u044f \u043d\u0430 \u0443\u0441\u0442\u043e\u0439\u0447\u0438\u0432\u043e\u0435 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435. \u0412 \u0434\u0440\u0443\u0433\u0438\u0445 \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u0430\u0445 \u0437\u0430\u043f\u0440\u0435\u0442\u043d\u044b\u043c\u0438 \u0434\u0435\u043b\u0430\u044e\u0442 \u043a\u043e\u043d\u043a\u0440\u0435\u0442\u043d\u044b\u0435 \u043a\u0430\u0442\u0435\u0433\u043e\u0440\u0438\u0438 \u2014 \u0432\u0440\u0435\u0434\u043d\u0443\u044e \u0435\u0434\u0443, \u043e\u0431\u0440\u0430\u0437\u044b \u0430\u043b\u043a\u043e\u0433\u043e\u043b\u044f, \u043e\u043f\u0440\u0435\u0434\u0435\u043b\u0451\u043d\u043d\u044b\u0435 \u044d\u043c\u043e\u0446\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u044b\u0435 \u043b\u0438\u0446\u0430, \u2014 \u0430 \u0441\u0430\u043c\u0443 \u0437\u0430\u0434\u0430\u0447\u0443 \u0447\u0430\u0441\u0442\u043e \u0441\u043e\u0432\u043c\u0435\u0449\u0430\u044e\u0442 \u0441 \u0444\u043b\u0430\u043d\u043a\u0435\u0440\u043d\u044b\u043c \u0438\u043b\u0438 \u043f\u043e\u0438\u0441\u043a\u043e\u0432\u044b\u043c \u044d\u043b\u0435\u043c\u0435\u043d\u0442\u043e\u043c, \u0447\u0442\u043e\u0431\u044b \u0441\u0438\u043b\u044c\u043d\u0435\u0435 \u043d\u0430\u0433\u0440\u0443\u0437\u0438\u0442\u044c \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435."},en:{about:"A stream of stimuli flashes one at a time, and most of them are \"go\" signals: you tap as fast as you can. A minority are \"no-go\" signals, and on those you must do nothing at all. The whole challenge is that tapping becomes a habit within seconds, so holding your finger still on a no-go takes real effort.",benefit:"It trains response inhibition, the ability to cancel an action you have already started to launch, along with the sustained attention needed to keep watching for the rare signal that says \"stop\". In everyday terms, it is the brake pedal of self-control rather than the accelerator.",history:"The go/no-go arrangement goes back to Franciscus Donders in 1868, who used it as one of three tasks in his subtraction method for timing mental processes. Over the twentieth century it was adopted by experimental and clinical psychology as a standard way to probe impulsivity and frontal-lobe function, and it later spread into neuroimaging, ADHD and addiction research, and consumer brain-training apps.",creator:"There is no single inventor. The paradigm is usually traced to the Dutch physiologist Franciscus Cornelis Donders and his 1868 work on reaction times (his \"C-task\"), and it was refined by many researchers since. It belongs to the experimental-psychology tradition of mental chronometry, not to any one author or year.",methods:"Keep the no-go signals genuinely rare, around 1 in 4 or fewer, because that is what builds the automatic urge you are learning to override. Aim for a comfortable but quick pace, and treat false alarms (tapping on a no-go) as the score that matters, not raw speed. If you never make mistakes you are going too slow, so push the rhythm until errors creep in, then hold there.",duration:"Short and frequent beats long and rare. Five to ten minutes a session, a few times a week, is plenty; the task is mentally fatiguing and accuracy falls off once attention drifts, so stop while you are still sharp rather than grinding out a long block.",research:"What is solid is narrow: with practice you make fewer false alarms and your inhibition on this kind of task gets faster and cleaner. Broad claims are much weaker. A well-known training study by Enge and colleagues (2014) found no convincing evidence that inhibition training transfers to untrained abilities, and reviews of executive-function training generally show little far transfer and no reliable IQ gains. Food-specific go/no-go training does reliably make \"no-go\" foods less appealing in the lab, but whether that durably changes real eating or drinking is still debated, so treat any promise beyond \"you get better at the task\" with caution.",rec:"Chase your false-alarm rate, not your reaction time: a session where you stayed accurate at a brisk pace beats a fast one littered with slips.",faq:[["Is this the same as the stop-signal task?","No. In go/no-go you decide from the signal itself whether to act, so you can hold back before moving. The stop-signal task tells you to act and then, a beat later, sometimes orders you to abort, which measures cancelling a response already in motion. They are related but tap slightly different braking processes."],["Will practising this make me less impulsive in real life?","Honestly, the evidence is thin. You will reliably get better at the task and at withholding responses inside it, but transfer to everyday impulse control or to general self-discipline is weak and contested. Use it as targeted attention-and-inhibition practice, not as a cure for impulsivity."],["I keep tapping on the no-go signals. Am I doing it wrong?","Not at all. Those slips, called commission errors, are the whole point of the exercise and the main thing it measures. The skill is to slow down just enough to catch them. If you make zero errors you are probably being too cautious to get any training value."]],variants:"Versions differ by how rare the no-go is and by what the signals are. The SART (Robertson, 1997) flips the ratio so that go is constant and no-go is rare, stressing sustained attention. Other variants use specific categories as no-go, such as junk foods, alcohol cues, or particular emotional faces, and the task is often combined with flanker or visual-search elements to load attention further."},es:{about:"Una sucesi\xf3n de est\xedmulos aparece de uno en uno, y la mayor\xeda son se\xf1ales de \"adelante\": tienes que pulsar lo m\xe1s r\xe1pido posible. Una minor\xeda son se\xf1ales de \"alto\", y ante ellas no debes hacer absolutamente nada. Toda la dificultad est\xe1 en que pulsar se convierte en un h\xe1bito en cuesti\xf3n de segundos, as\xed que mantener el dedo quieto ante una se\xf1al de alto exige un esfuerzo real.",benefit:"Entrena la inhibici\xf3n de la respuesta, la capacidad de cancelar una acci\xf3n que ya hab\xedas empezado a poner en marcha, junto con la atenci\xf3n sostenida necesaria para seguir vigilando esa se\xf1al poco frecuente que dice \"para\". En t\xe9rminos cotidianos, es el pedal de freno del autocontrol, no el acelerador.",history:"El esquema go/no-go se remonta a Franciscus Donders en 1868, que lo emple\xf3 como una de las tres tareas de su m\xe9todo de sustracci\xf3n para cronometrar los procesos mentales. A lo largo del siglo XX, la psicolog\xeda experimental y cl\xednica lo adopt\xf3 como una forma est\xe1ndar de sondear la impulsividad y el funcionamiento del l\xf3bulo frontal, y m\xe1s tarde se extendi\xf3 a la neuroimagen, a la investigaci\xf3n sobre el TDAH y las adicciones, y a las aplicaciones comerciales de entrenamiento cerebral.",creator:"No hay un \xfanico inventor. El paradigma suele atribuirse al fisi\xf3logo neerland\xe9s Franciscus Cornelis Donders y a su trabajo de 1868 sobre los tiempos de reacci\xf3n (su \"tarea C\"), y desde entonces lo han refinado numerosos investigadores. Pertenece a la tradici\xf3n de la cronometr\xeda mental de la psicolog\xeda experimental, no a un autor ni a un a\xf1o concretos.",methods:"Mant\xe9n las se\xf1ales de alto verdaderamente escasas, alrededor de una de cada cuatro o menos, porque es eso lo que crea el impulso autom\xe1tico que est\xe1s aprendiendo a frenar. Busca un ritmo c\xf3modo pero \xe1gil, y considera las falsas alarmas (pulsar ante un alto) como la puntuaci\xf3n que importa, no la velocidad bruta. Si nunca cometes errores es que vas demasiado lento, as\xed que acelera el ritmo hasta que empiecen a colarse fallos y mantente ah\xed.",duration:"Corto y frecuente gana a largo y espor\xe1dico. Cinco a diez minutos por sesi\xf3n, unas cuantas veces por semana, es m\xe1s que suficiente; la tarea fatiga mentalmente y la precisi\xf3n cae en cuanto la atenci\xf3n se dispersa, as\xed que para mientras sigas afilado en lugar de arrastrarte por un bloque largo.",research:"Lo s\xf3lido es limitado: con la pr\xe1ctica cometes menos falsas alarmas y tu inhibici\xf3n en este tipo de tarea se vuelve m\xe1s r\xe1pida y limpia. Las afirmaciones amplias son mucho m\xe1s d\xe9biles. Un conocido estudio de entrenamiento de Enge y colaboradores (2014) no encontr\xf3 pruebas convincentes de que el entrenamiento de la inhibici\xf3n se transfiera a capacidades no entrenadas, y las revisiones del entrenamiento de las funciones ejecutivas suelen mostrar poca transferencia lejana y ninguna mejora fiable del coeficiente intelectual. El entrenamiento go/no-go con alimentos concretos s\xed logra de forma fiable que los alimentos asociados al \"alto\" resulten menos apetecibles en el laboratorio, pero sigue debati\xe9ndose si eso modifica de forma duradera lo que se come o se bebe en la vida real, as\xed que toma con cautela cualquier promesa que vaya m\xe1s all\xe1 de \"mejoras en la tarea\".",rec:"Persigue tu tasa de falsas alarmas, no tu tiempo de reacci\xf3n: una sesi\xf3n en la que mantuviste la precisi\xf3n a buen ritmo vale m\xe1s que una r\xe1pida plagada de descuidos.",faq:[["\xbfEs lo mismo que la tarea de se\xf1al de alto?","No. En go/no-go decides a partir de la propia se\xf1al si act\xfaas o no, as\xed que puedes contenerte antes de moverte. La tarea de se\xf1al de alto te ordena actuar y luego, un instante despu\xe9s, a veces te manda abortar, lo que mide la cancelaci\xf3n de una respuesta que ya est\xe1 en marcha. Est\xe1n emparentadas, pero ponen a prueba procesos de frenado algo distintos."],["\xbfPracticar esto me har\xe1 menos impulsivo en la vida real?","Sinceramente, la evidencia es escasa. Mejorar\xe1s de forma fiable en la tarea y en contener respuestas dentro de ella, pero la transferencia al control de impulsos cotidiano o a la autodisciplina general es d\xe9bil y discutida. \xdasalo como pr\xe1ctica dirigida de atenci\xf3n e inhibici\xf3n, no como una cura para la impulsividad."],["Sigo pulsando en las se\xf1ales de alto. \xbfLo estoy haciendo mal?","En absoluto. Esos descuidos, llamados errores de comisi\xf3n, son justamente el objetivo del ejercicio y lo principal que mide. La destreza consiste en ir lo bastante despacio como para atraparlos. Si no cometes ning\xfan error, seguramente est\xe9s siendo demasiado cauto para sacarle alg\xfan provecho al entrenamiento."]],variants:"Las versiones difieren en lo escaso que es el no-go y en cu\xe1les son las se\xf1ales. El SART (Robertson, 1997) invierte la proporci\xf3n de modo que el \"adelante\" es constante y el \"alto\" es raro, poniendo el acento en la atenci\xf3n sostenida. Otras variantes usan categor\xedas concretas como no-go, por ejemplo comida basura, se\xf1ales relacionadas con el alcohol o determinadas caras emocionales, y la tarea suele combinarse con elementos de flancos o de b\xfasqueda visual para exigir a\xfan m\xe1s a la atenci\xf3n."},de:{about:"Ein Strom von Reizen blitzt einer nach dem anderen auf, und die meisten davon sind \"Go\"-Signale: Du tippst so schnell wie m\xf6glich. Eine Minderheit sind \"No-Go\"-Signale, und bei denen darfst du gar nichts tun. Der ganze Reiz liegt darin, dass das Tippen schon nach wenigen Sekunden zur Gewohnheit wird, sodass es echte M\xfche kostet, den Finger bei einem No-Go still zu halten.",benefit:"Trainiert wird die Reaktionshemmung, also die F\xe4higkeit, eine bereits angesto\xdfene Handlung abzubrechen, zusammen mit der Daueraufmerksamkeit, die n\xf6tig ist, um nach dem seltenen Signal Ausschau zu halten, das \"Stopp\" sagt. Im Alltag gesprochen ist das eher das Bremspedal der Selbstkontrolle als das Gaspedal.",history:"Die Go/No-Go-Anordnung geht auf Franciscus Donders im Jahr 1868 zur\xfcck, der sie als eine von drei Aufgaben in seiner Subtraktionsmethode zur Messung mentaler Prozesse nutzte. Im Laufe des 20. Jahrhunderts \xfcbernahmen die experimentelle und die klinische Psychologie sie als Standardverfahren, um Impulsivit\xe4t und Stirnhirnfunktion zu untersuchen, und sp\xe4ter verbreitete sie sich in der Bildgebung, der ADHS- und Suchtforschung sowie in kommerziellen Gehirntrainings-Apps.",creator:"Es gibt keinen einzelnen Erfinder. Das Paradigma wird \xfcblicherweise auf den niederl\xe4ndischen Physiologen Franciscus Cornelis Donders und seine Arbeit zu Reaktionszeiten von 1868 zur\xfcckgef\xfchrt (seine \"C-Aufgabe\") und wurde seither von vielen Forschenden verfeinert. Es geh\xf6rt zur experimentalpsychologischen Tradition der mentalen Chronometrie, nicht zu einem bestimmten Autor oder Jahr.",methods:"Halte die No-Go-Signale wirklich selten, etwa 1 von 4 oder weniger, denn genau das erzeugt den automatischen Drang, den du zu \xfcberwinden lernst. Strebe ein angenehmes, aber z\xfcgiges Tempo an und betrachte Fehlalarme (Tippen bei einem No-Go) als die Kennzahl, auf die es ankommt, nicht die reine Geschwindigkeit. Wenn dir nie ein Fehler unterl\xe4uft, bist du zu langsam; treib den Rhythmus also an, bis sich Fehler einschleichen, und halte dann dieses Niveau.",duration:"Kurz und h\xe4ufig schl\xe4gt lang und selten. F\xfcnf bis zehn Minuten pro Sitzung, ein paar Mal die Woche, reichen v\xf6llig; die Aufgabe erm\xfcdet geistig, und die Genauigkeit sackt ab, sobald die Aufmerksamkeit nachl\xe4sst. H\xf6r also auf, solange du noch scharf bist, statt einen langen Block durchzuackern.",research:"Was gesichert ist, ist eng begrenzt: Mit \xdcbung machst du weniger Fehlalarme, und deine Hemmung bei dieser Art Aufgabe wird schneller und sauberer. Weitreichendere Behauptungen stehen auf deutlich schw\xe4cheren F\xfc\xdfen. Eine bekannte Trainingsstudie von Enge und Kollegen (2014) fand keinen \xfcberzeugenden Beleg daf\xfcr, dass sich Hemmungstraining auf unge\xfcbte F\xe4higkeiten \xfcbertr\xe4gt, und \xdcbersichtsarbeiten zum Training exekutiver Funktionen zeigen allgemein kaum Fern-Transfer und keine verl\xe4sslichen IQ-Gewinne. Nahrungsspezifisches Go/No-Go-Training macht \"No-Go\"-Lebensmittel im Labor zuverl\xe4ssig weniger attraktiv, ob das jedoch dauerhaft das reale Ess- oder Trinkverhalten \xe4ndert, ist weiter umstritten. Behandle daher jedes Versprechen jenseits von \"du wirst in der Aufgabe besser\" mit Vorsicht.",rec:"Jage deiner Fehlalarmquote nach, nicht deiner Reaktionszeit: Eine Sitzung, in der du bei z\xfcgigem Tempo treffsicher geblieben bist, ist mehr wert als eine schnelle voller Patzer.",faq:[["Ist das dasselbe wie die Stopp-Signal-Aufgabe?","Nein. Beim Go/No-Go entscheidest du anhand des Signals selbst, ob du handelst, du kannst dich also zur\xfcckhalten, bevor du dich bewegst. Die Stopp-Signal-Aufgabe fordert dich zum Handeln auf und befiehlt dir dann einen Augenblick sp\xe4ter manchmal abzubrechen, was das Stoppen einer bereits laufenden Reaktion misst. Sie sind verwandt, beanspruchen aber leicht unterschiedliche Bremsprozesse."],["Werde ich durch das \xdcben im echten Leben weniger impulsiv?","Ehrlich gesagt ist die Beleglage d\xfcnn. Du wirst zuverl\xe4ssig besser in der Aufgabe und darin, Reaktionen innerhalb von ihr zu unterdr\xfccken, aber die \xdcbertragung auf die allt\xe4gliche Impulskontrolle oder auf allgemeine Selbstdisziplin ist schwach und umstritten. Nutze es als gezieltes Aufmerksamkeits- und Hemmungstraining, nicht als Heilmittel gegen Impulsivit\xe4t."],["Ich tippe st\xe4ndig bei den No-Go-Signalen. Mache ich etwas falsch?","\xdcberhaupt nicht. Diese Patzer, Kommissionsfehler genannt, sind der eigentliche Sinn der \xdcbung und das, was sie haupts\xe4chlich misst. Die Kunst besteht darin, gerade so weit abzubremsen, dass du sie abf\xe4ngst. Wenn dir null Fehler unterlaufen, bist du wahrscheinlich zu vorsichtig, um irgendeinen Trainingseffekt zu erzielen."]],variants:"Die Versionen unterscheiden sich darin, wie selten das No-Go ist und worin die Signale bestehen. Der SART (Robertson, 1997) dreht das Verh\xe4ltnis um, sodass Go konstant und No-Go selten ist, was die Daueraufmerksamkeit betont. Andere Varianten nutzen bestimmte Kategorien als No-Go, etwa ungesundes Essen, Alkoholreize oder bestimmte emotionale Gesichter, und die Aufgabe wird oft mit Flanker- oder Suchaufgaben-Elementen kombiniert, um die Aufmerksamkeit weiter zu belasten."},pt:{about:"Uma sequ\xeancia de est\xedmulos pisca um de cada vez, e a maioria deles s\xe3o sinais de \"vai\": voc\xea toca o mais r\xe1pido que conseguir. Uma minoria s\xe3o sinais de \"n\xe3o vai\", e nesses voc\xea n\xe3o pode fazer absolutamente nada. O desafio inteiro \xe9 que tocar vira h\xe1bito em quest\xe3o de segundos, ent\xe3o segurar o dedo parado num \"n\xe3o vai\" exige esfor\xe7o de verdade.",benefit:"Treina a inibi\xe7\xe3o da resposta, a capacidade de cancelar uma a\xe7\xe3o que voc\xea j\xe1 come\xe7ou a disparar, junto com a aten\xe7\xe3o sustentada necess\xe1ria para continuar atento ao sinal raro que manda \"parar\". Em termos do dia a dia, \xe9 o pedal de freio do autocontrole, e n\xe3o o acelerador.",history:"O arranjo vai/n\xe3o vai remonta a Franciscus Donders, em 1868, que o usou como uma das tr\xeas tarefas no seu m\xe9todo de subtra\xe7\xe3o para cronometrar processos mentais. Ao longo do s\xe9culo XX foi adotado pela psicologia experimental e cl\xednica como uma forma padr\xe3o de investigar a impulsividade e a fun\xe7\xe3o do lobo frontal, e mais tarde se espalhou para a neuroimagem, a pesquisa sobre TDAH e depend\xeancia, e os aplicativos comerciais de treino cerebral.",creator:"N\xe3o h\xe1 um \xfanico inventor. O paradigma costuma ser atribu\xeddo ao fisiologista holand\xeas Franciscus Cornelis Donders e ao seu trabalho de 1868 sobre tempos de rea\xe7\xe3o (a sua \"tarefa C\"), e foi refinado por muitos pesquisadores desde ent\xe3o. Pertence \xe0 tradi\xe7\xe3o da cronometria mental dentro da psicologia experimental, e n\xe3o a um autor ou ano espec\xedfico.",methods:"Mantenha os sinais de \"n\xe3o vai\" genuinamente raros, em torno de 1 a cada 4 ou menos, porque \xe9 isso que constr\xf3i o impulso autom\xe1tico que voc\xea est\xe1 aprendendo a vencer. Busque um ritmo confort\xe1vel mas r\xe1pido, e trate os alarmes falsos (tocar num \"n\xe3o vai\") como a pontua\xe7\xe3o que importa, n\xe3o a velocidade pura. Se voc\xea nunca erra, est\xe1 indo devagar demais, ent\xe3o acelere o ritmo at\xe9 os erros come\xe7arem a aparecer e fique nesse ponto.",duration:"Curto e frequente vence longo e espor\xe1dico. Cinco a dez minutos por sess\xe3o, algumas vezes por semana, j\xe1 basta; a tarefa \xe9 mentalmente cansativa e a precis\xe3o despenca quando a aten\xe7\xe3o dispersa, ent\xe3o pare enquanto ainda est\xe1 afiado em vez de empurrar um bloco longo.",research:"O que \xe9 s\xf3lido \xe9 limitado: com a pr\xe1tica voc\xea comete menos alarmes falsos e a sua inibi\xe7\xe3o nesse tipo de tarefa fica mais r\xe1pida e mais limpa. Afirma\xe7\xf5es amplas s\xe3o bem mais fr\xe1geis. Um estudo de treino bastante conhecido de Enge e colegas (2014) n\xe3o encontrou evid\xeancia convincente de que o treino de inibi\xe7\xe3o se transfira para habilidades n\xe3o treinadas, e revis\xf5es sobre treino de fun\xe7\xf5es executivas em geral mostram pouca transfer\xeancia distante e nenhum ganho confi\xe1vel de QI. O treino vai/n\xe3o vai espec\xedfico para alimentos de fato torna os alimentos \"n\xe3o vai\" menos atraentes em laborat\xf3rio, mas se isso muda de forma duradoura o comer ou o beber na vida real ainda \xe9 discutido, ent\xe3o encare com cautela qualquer promessa al\xe9m de \"voc\xea fica melhor na tarefa\".",rec:"Persiga a sua taxa de alarmes falsos, n\xe3o o seu tempo de rea\xe7\xe3o: uma sess\xe3o em que voc\xea se manteve preciso num ritmo \xe1gil vale mais do que uma r\xe1pida e cheia de escorreg\xf5es.",faq:[["Isso \xe9 a mesma coisa que a tarefa de sinal de parada?","N\xe3o. No vai/n\xe3o vai voc\xea decide, a partir do pr\xf3prio sinal, se vai agir, ent\xe3o consegue se conter antes de se mover. A tarefa de sinal de parada manda voc\xea agir e, um instante depois, \xe0s vezes ordena que aborte, o que mede o cancelamento de uma resposta j\xe1 em movimento. S\xe3o relacionadas, mas acionam processos de frenagem um pouco diferentes."],["Praticar isso vai me deixar menos impulsivo na vida real?","Sinceramente, a evid\xeancia \xe9 fraca. Voc\xea vai melhorar de forma confi\xe1vel na tarefa e em conter respostas dentro dela, mas a transfer\xeancia para o controle de impulsos do dia a dia ou para a autodisciplina geral \xe9 fr\xe1gil e contestada. Use como pr\xe1tica direcionada de aten\xe7\xe3o e inibi\xe7\xe3o, n\xe3o como cura para a impulsividade."],["Eu fico tocando nos sinais de \"n\xe3o vai\". Estou fazendo errado?","De jeito nenhum. Esses escorreg\xf5es, chamados de erros de comiss\xe3o, s\xe3o justamente o ponto do exerc\xedcio e a principal coisa que ele mede. A habilidade est\xe1 em desacelerar s\xf3 o suficiente para peg\xe1-los. Se voc\xea n\xe3o comete nenhum erro, provavelmente est\xe1 sendo cauteloso demais para extrair qualquer valor de treino."]],variants:"As vers\xf5es diferem em qu\xe3o raro \xe9 o \"n\xe3o vai\" e em quais s\xe3o os sinais. O SART (Robertson, 1997) inverte a propor\xe7\xe3o, deixando o \"vai\" constante e o \"n\xe3o vai\" raro, enfatizando a aten\xe7\xe3o sustentada. Outras variantes usam categorias espec\xedficas como \"n\xe3o vai\", como comidas de baixo valor nutricional, pistas de \xe1lcool ou determinados rostos emocionais, e a tarefa costuma ser combinada com elementos de flanker ou de busca visual para sobrecarregar ainda mais a aten\xe7\xe3o."},hi:{about:"\u090f\u0915-\u090f\u0915 \u0915\u0930\u0915\u0947 \u0938\u0902\u0915\u0947\u0924\u094b\u0902 \u0915\u0940 \u0927\u093e\u0930\u093e \u091a\u092e\u0915\u0924\u0940 \u0939\u0948, \u0914\u0930 \u0907\u0928\u092e\u0947\u0902 \u0938\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e\u0924\u0930 \"go\" \u0938\u0902\u0915\u0947\u0924 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902: \u0907\u0928 \u092a\u0930 \u0906\u092a \u091c\u093f\u0924\u0928\u0940 \u091c\u0932\u094d\u0926\u0940 \u0939\u094b \u0938\u0915\u0947 \u091f\u0948\u092a \u0915\u0930\u0924\u0947 \u0939\u0948\u0902\u0964 \u0925\u094b\u0921\u093c\u0947-\u0938\u0947 \"no-go\" \u0938\u0902\u0915\u0947\u0924 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u0909\u0928 \u092a\u0930 \u0906\u092a\u0915\u094b \u092c\u093f\u0932\u0915\u0941\u0932 \u0915\u0941\u091b \u0928\u0939\u0940\u0902 \u0915\u0930\u0928\u093e \u0939\u094b\u0924\u093e\u0964 \u092a\u0942\u0930\u0940 \u091a\u0941\u0928\u094c\u0924\u0940 \u092f\u0939 \u0939\u0948 \u0915\u093f \u0915\u0941\u091b \u0939\u0940 \u0938\u0947\u0915\u0902\u0921\u094b\u0902 \u092e\u0947\u0902 \u091f\u0948\u092a \u0915\u0930\u0928\u093e \u090f\u0915 \u0906\u0926\u0924 \u092c\u0928 \u091c\u093e\u0924\u093e \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0915\u093f\u0938\u0940 no-go \u092a\u0930 \u0909\u0901\u0917\u0932\u0940 \u0930\u094b\u0915\u0947 \u0930\u0916\u0928\u093e \u0938\u091a\u092e\u0941\u091a \u092e\u0947\u0939\u0928\u0924 \u092e\u093e\u0901\u0917\u0924\u093e \u0939\u0948\u0964",benefit:"\u092f\u0939 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0928\u093f\u0930\u094b\u0927 (response inhibition) \u0938\u093e\u0927\u0924\u093e \u0939\u0948 \u2014 \u092f\u093e\u0928\u0940 \u091c\u093f\u0938 \u0915\u094d\u0930\u093f\u092f\u093e \u0915\u094b \u0906\u092a \u0936\u0941\u0930\u0942 \u0915\u0930 \u0939\u0940 \u091a\u0941\u0915\u0947 \u0925\u0947, \u0909\u0938\u0947 \u0930\u094b\u0915 \u0926\u0947\u0928\u0947 \u0915\u0940 \u0915\u094d\u0937\u092e\u0924\u093e \u2014 \u0938\u093e\u0925 \u0939\u0940 \u0935\u0939 \u091f\u093f\u0915\u093e\u090a \u0927\u094d\u092f\u093e\u0928 \u092d\u0940, \u091c\u094b \u0909\u0938 \u0926\u0941\u0930\u094d\u0932\u092d \u0938\u0902\u0915\u0947\u0924 \u092a\u0930 \u0928\u091c\u093c\u0930 \u0930\u0916\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u091a\u093e\u0939\u093f\u090f \u091c\u094b \"\u0930\u0941\u0915\u094b\" \u0915\u0939\u0924\u093e \u0939\u0948\u0964 \u0906\u0938\u093e\u0928 \u0936\u092c\u094d\u0926\u094b\u0902 \u092e\u0947\u0902, \u092f\u0939 \u0906\u0924\u094d\u092e-\u0928\u093f\u092f\u0902\u0924\u094d\u0930\u0923 \u0915\u093e \u092c\u094d\u0930\u0947\u0915 \u092a\u0948\u0921\u0932 \u0939\u0948, \u090f\u0915\u094d\u0938\u0947\u0932\u0930\u0947\u091f\u0930 \u0928\u0939\u0940\u0902\u0964",history:"go/no-go \u0935\u094d\u092f\u0935\u0938\u094d\u0925\u093e 1868 \u092e\u0947\u0902 Franciscus Donders \u0924\u0915 \u091c\u093e\u0924\u0940 \u0939\u0948, \u091c\u093f\u0928\u094d\u0939\u094b\u0902\u0928\u0947 \u092e\u093e\u0928\u0938\u093f\u0915 \u092a\u094d\u0930\u0915\u094d\u0930\u093f\u092f\u093e\u0913\u0902 \u0915\u093e \u0938\u092e\u092f \u092e\u093e\u092a\u0928\u0947 \u0915\u0940 \u0905\u092a\u0928\u0940 \u0918\u091f\u093e\u0935-\u0935\u093f\u0927\u093f (subtraction method) \u0915\u0947 \u0924\u0940\u0928 \u0915\u093e\u0930\u094d\u092f\u094b\u0902 \u092e\u0947\u0902 \u0938\u0947 \u090f\u0915 \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u0907\u0938\u0947 \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0915\u093f\u092f\u093e\u0964 \u092c\u0940\u0938\u0935\u0940\u0902 \u0938\u0926\u0940 \u092e\u0947\u0902 \u092a\u094d\u0930\u092f\u094b\u0917\u093e\u0924\u094d\u092e\u0915 \u0914\u0930 \u0915\u094d\u0932\u093f\u0928\u093f\u0915\u0932 \u092e\u0928\u094b\u0935\u093f\u091c\u094d\u091e\u093e\u0928 \u0928\u0947 \u0907\u0938\u0947 \u0906\u0935\u0947\u0917 \u0914\u0930 \u092b\u093c\u094d\u0930\u0902\u091f\u0932-\u0932\u094b\u092c \u0915\u0940 \u0915\u093e\u0930\u094d\u092f\u092a\u094d\u0930\u0923\u093e\u0932\u0940 \u091c\u093e\u0901\u091a\u0928\u0947 \u0915\u0947 \u090f\u0915 \u092e\u093e\u0928\u0915 \u0924\u0930\u0940\u0915\u093c\u0947 \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u0905\u092a\u0928\u093e\u092f\u093e, \u0914\u0930 \u092c\u093e\u0926 \u092e\u0947\u0902 \u092f\u0939 \u0928\u094d\u092f\u0942\u0930\u094b\u0907\u092e\u0947\u091c\u093f\u0902\u0917, ADHD \u0924\u0925\u093e \u0928\u0936\u0947 \u0915\u0947 \u0936\u094b\u0927, \u0914\u0930 \u0909\u092a\u092d\u094b\u0915\u094d\u0924\u093e \u092c\u094d\u0930\u0947\u0928-\u091f\u094d\u0930\u0947\u0928\u093f\u0902\u0917 \u0910\u092a\u094d\u0938 \u0924\u0915 \u092b\u0948\u0932 \u0917\u092f\u093e\u0964",creator:"\u0907\u0938\u0915\u093e \u0915\u094b\u0908 \u090f\u0915 \u0906\u0935\u093f\u0937\u094d\u0915\u093e\u0930\u0915 \u0928\u0939\u0940\u0902 \u0939\u0948\u0964 \u092f\u0939 \u0922\u093e\u0901\u091a\u093e \u0906\u092e\u0924\u094c\u0930 \u092a\u0930 \u0921\u091a \u092b\u093c\u093f\u091c\u093c\u093f\u092f\u094b\u0932\u0949\u091c\u093f\u0938\u094d\u091f Franciscus Cornelis Donders \u0914\u0930 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0938\u092e\u092f \u092a\u0930 \u0909\u0928\u0915\u0947 1868 \u0915\u0947 \u0915\u093e\u092e (\u0909\u0928\u0915\u093e \"C-task\") \u0938\u0947 \u091c\u094b\u0921\u093c\u093e \u091c\u093e\u0924\u093e \u0939\u0948, \u0914\u0930 \u0924\u092c \u0938\u0947 \u0915\u0908 \u0936\u094b\u0927\u0915\u0930\u094d\u0924\u093e\u0913\u0902 \u0928\u0947 \u0907\u0938\u0947 \u0928\u093f\u0916\u093e\u0930\u093e\u0964 \u092f\u0939 \u092e\u093e\u0928\u0938\u093f\u0915 \u0915\u093e\u0932\u092e\u093e\u092a\u0928 (mental chronometry) \u0915\u0940 \u092a\u094d\u0930\u092f\u094b\u0917\u093e\u0924\u094d\u092e\u0915-\u092e\u0928\u094b\u0935\u093f\u091c\u094d\u091e\u093e\u0928 \u092a\u0930\u0902\u092a\u0930\u093e \u0915\u093e \u0939\u093f\u0938\u094d\u0938\u093e \u0939\u0948, \u0915\u093f\u0938\u0940 \u090f\u0915 \u0932\u0947\u0916\u0915 \u092f\u093e \u0935\u0930\u094d\u0937 \u0915\u0940 \u0926\u0947\u0928 \u0928\u0939\u0940\u0902\u0964",methods:"no-go \u0938\u0902\u0915\u0947\u0924\u094b\u0902 \u0915\u094b \u0938\u091a\u092e\u0941\u091a \u0926\u0941\u0930\u094d\u0932\u092d \u0930\u0916\u0947\u0902 \u2014 \u0915\u093c\u0930\u0940\u092c 4 \u092e\u0947\u0902 \u0938\u0947 1 \u092f\u093e \u0909\u0938\u0938\u0947 \u092d\u0940 \u0915\u092e \u2014 \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u092f\u0939\u0940 \u0935\u0939 \u0938\u094d\u0935\u091a\u093e\u0932\u093f\u0924 \u0906\u0935\u0947\u0917 \u092a\u0948\u0926\u093e \u0915\u0930\u0924\u093e \u0939\u0948 \u091c\u093f\u0938\u0947 \u0930\u094b\u0915\u0928\u093e \u0906\u092a \u0938\u0940\u0916 \u0930\u0939\u0947 \u0939\u0948\u0902\u0964 \u090f\u0915 \u0906\u0930\u093e\u092e\u0926\u0947\u0939 \u092a\u0930 \u0924\u0947\u091c\u093c \u0930\u092b\u093c\u094d\u0924\u093e\u0930 \u0930\u0916\u0928\u0947 \u0915\u093e \u0932\u0915\u094d\u0937\u094d\u092f \u0930\u0916\u0947\u0902, \u0914\u0930 \u0915\u091a\u094d\u091a\u0940 \u0930\u092b\u093c\u094d\u0924\u093e\u0930 \u0915\u0947 \u092c\u091c\u093e\u092f false alarm (no-go \u092a\u0930 \u091f\u0948\u092a \u0915\u0930 \u0926\u0947\u0928\u093e) \u0915\u094b \u0939\u0940 \u0905\u0938\u0932\u0940 \u0938\u094d\u0915\u094b\u0930 \u092e\u093e\u0928\u0947\u0902\u0964 \u0905\u0917\u0930 \u0906\u092a \u0915\u092d\u0940 \u0917\u093c\u0932\u0924\u0940 \u0939\u0940 \u0928\u0939\u0940\u0902 \u0915\u0930\u0924\u0947, \u0924\u094b \u0906\u092a \u091c\u093c\u0930\u0942\u0930\u0924 \u0938\u0947 \u0927\u0940\u092e\u0947 \u091a\u0932 \u0930\u0939\u0947 \u0939\u0948\u0902, \u0907\u0938\u0932\u093f\u090f \u0932\u092f \u0915\u094b \u0924\u092c \u0924\u0915 \u0924\u0947\u091c\u093c \u0915\u0930\u0947\u0902 \u091c\u092c \u0924\u0915 \u0917\u093c\u0932\u0924\u093f\u092f\u093e\u0901 \u0906\u0928\u0947 \u0928 \u0932\u0917\u0947\u0902, \u0914\u0930 \u092b\u093f\u0930 \u0935\u0939\u0940\u0902 \u091f\u093f\u0915\u0947 \u0930\u0939\u0947\u0902\u0964",duration:"\u091b\u094b\u091f\u093e \u0914\u0930 \u092c\u093e\u0930-\u092c\u093e\u0930, \u0932\u0902\u092c\u0947-\u0914\u0930-\u0915\u092d\u0940-\u0915\u092d\u093e\u0930 \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u0939\u0948\u0964 \u090f\u0915 \u0938\u0924\u094d\u0930 \u092e\u0947\u0902 \u092a\u093e\u0901\u091a \u0938\u0947 \u0926\u0938 \u092e\u093f\u0928\u091f, \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u0915\u0941\u091b \u092c\u093e\u0930, \u0915\u093e\u092b\u093c\u0940 \u0939\u0948\u0902; \u092f\u0939 \u091f\u093e\u0938\u094d\u0915 \u092e\u093e\u0928\u0938\u093f\u0915 \u0930\u0942\u092a \u0938\u0947 \u0925\u0915\u093e \u0926\u0947\u0928\u0947 \u0935\u093e\u0932\u093e \u0939\u0948 \u0914\u0930 \u0927\u094d\u092f\u093e\u0928 \u092d\u091f\u0915\u0924\u0947 \u0939\u0940 \u0938\u091f\u0940\u0915\u0924\u093e \u0917\u093f\u0930 \u091c\u093e\u0924\u0940 \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0932\u0902\u092c\u093e \u092c\u094d\u0932\u0949\u0915 \u0930\u0917\u0921\u093c\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u0924\u092c \u0930\u0941\u0915 \u091c\u093e\u090f\u0901 \u091c\u092c \u0906\u092a \u0905\u092c \u092d\u0940 \u091a\u0941\u0938\u094d\u0924 \u0939\u094b\u0902\u0964",research:"\u091c\u094b \u092a\u0941\u0916\u093c\u094d\u0924\u093e \u0939\u0948 \u0935\u0939 \u0938\u0902\u0915\u0930\u093e \u0939\u0948: \u0905\u092d\u094d\u092f\u093e\u0938 \u0938\u0947 \u0906\u092a \u0915\u092e false alarm \u0915\u0930\u0924\u0947 \u0939\u0948\u0902 \u0914\u0930 \u0907\u0938 \u0924\u0930\u0939 \u0915\u0947 \u091f\u093e\u0938\u094d\u0915 \u092a\u0930 \u0906\u092a\u0915\u093e \u0928\u093f\u0930\u094b\u0927 \u0924\u0947\u091c\u093c \u0914\u0930 \u0938\u093e\u092b\u093c \u0939\u094b \u091c\u093e\u0924\u093e \u0939\u0948\u0964 \u0935\u094d\u092f\u093e\u092a\u0915 \u0926\u093e\u0935\u0947 \u0915\u0939\u0940\u0902 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0915\u092e\u091c\u093c\u094b\u0930 \u0939\u0948\u0902\u0964 Enge \u0914\u0930 \u0938\u093e\u0925\u093f\u092f\u094b\u0902 \u0915\u0947 \u090f\u0915 \u092e\u0936\u0939\u0942\u0930 \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u0905\u0927\u094d\u092f\u092f\u0928 (2014) \u092e\u0947\u0902 \u0907\u0938\u0915\u093e \u0915\u094b\u0908 \u0920\u094b\u0938 \u0938\u092c\u0942\u0924 \u0928\u0939\u0940\u0902 \u092e\u093f\u0932\u093e \u0915\u093f \u0928\u093f\u0930\u094b\u0927-\u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u092c\u093f\u0928\u093e-\u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u093f\u0924 \u0915\u094d\u0937\u092e\u0924\u093e\u0913\u0902 \u0924\u0915 \u092a\u0939\u0941\u0901\u091a\u0924\u093e \u0939\u0948, \u0914\u0930 \u0915\u093e\u0930\u094d\u092f\u0915\u093e\u0930\u0940-\u0915\u093e\u0930\u094d\u092f (executive-function) \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u0915\u0940 \u0938\u092e\u0940\u0915\u094d\u0937\u093e\u090f\u0901 \u0906\u092e\u0924\u094c\u0930 \u092a\u0930 \u092c\u0939\u0941\u0924 \u0915\u092e far transfer \u0914\u0930 \u0915\u094b\u0908 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 IQ-\u0932\u093e\u092d \u0928\u0939\u0940\u0902 \u0926\u093f\u0916\u093e\u0924\u0940\u0902\u0964 \u092d\u094b\u091c\u0928-\u0935\u093f\u0936\u093f\u0937\u094d\u091f go/no-go \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u092a\u094d\u0930\u092f\u094b\u0917\u0936\u093e\u0932\u093e \u092e\u0947\u0902 \"no-go\" \u0935\u093e\u0932\u0947 \u0916\u093e\u0926\u094d\u092f \u092a\u0926\u093e\u0930\u094d\u0925\u094b\u0902 \u0915\u094b \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0922\u0902\u0917 \u0938\u0947 \u0915\u092e \u0932\u0941\u092d\u093e\u0935\u0928\u093e \u092c\u0928\u093e \u0926\u0947\u0924\u093e \u0939\u0948, \u092a\u0930 \u0907\u0938\u0938\u0947 \u0905\u0938\u0932 \u0916\u093e\u0928-\u092a\u093e\u0928 \u092f\u093e \u092a\u0940\u0928\u0947 \u092e\u0947\u0902 \u0915\u094b\u0908 \u091f\u093f\u0915\u093e\u090a \u092c\u0926\u0932\u093e\u0935 \u0906\u0924\u093e \u0939\u0948 \u092f\u093e \u0928\u0939\u0940\u0902, \u092f\u0939 \u0905\u092c \u092d\u0940 \u092c\u0939\u0938 \u092e\u0947\u0902 \u0939\u0948 \u2014 \u0907\u0938\u0932\u093f\u090f \"\u0906\u092a \u0907\u0938 \u091f\u093e\u0938\u094d\u0915 \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902\" \u0938\u0947 \u0906\u0917\u0947 \u0915\u0947 \u0915\u093f\u0938\u0940 \u092d\u0940 \u0935\u093e\u0926\u0947 \u0915\u094b \u0938\u093e\u0935\u0927\u093e\u0928\u0940 \u0938\u0947 \u0932\u0947\u0902\u0964",rec:"\u0905\u092a\u0928\u0940 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0917\u0924\u093f \u0915\u0947 \u092c\u091c\u093e\u092f \u0905\u092a\u0928\u0947 false-alarm \u0930\u0947\u091f \u0915\u0947 \u092a\u0940\u091b\u0947 \u0926\u094c\u0921\u093c\u0947\u0902: \u090f\u0915 \u0938\u0924\u094d\u0930 \u091c\u093f\u0938\u092e\u0947\u0902 \u0906\u092a \u0924\u0947\u091c\u093c \u0930\u092b\u093c\u094d\u0924\u093e\u0930 \u092a\u0930 \u0938\u091f\u0940\u0915 \u092c\u0928\u0947 \u0930\u0939\u0947, \u0909\u0938 \u0924\u0947\u091c\u093c \u0938\u0924\u094d\u0930 \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u0939\u0948 \u091c\u094b \u0917\u093c\u0932\u0924\u093f\u092f\u094b\u0902 \u0938\u0947 \u092d\u0930\u093e \u0939\u094b\u0964",faq:[["\u0915\u094d\u092f\u093e \u092f\u0939 stop-signal \u091f\u093e\u0938\u094d\u0915 \u091c\u0948\u0938\u093e \u0939\u0940 \u0939\u0948?","\u0928\u0939\u0940\u0902\u0964 go/no-go \u092e\u0947\u0902 \u0906\u092a \u0938\u0902\u0915\u0947\u0924 \u0938\u0947 \u0939\u0940 \u0924\u092f \u0915\u0930\u0924\u0947 \u0939\u0948\u0902 \u0915\u093f \u0915\u094d\u0930\u093f\u092f\u093e \u0915\u0930\u0928\u0940 \u0939\u0948 \u092f\u093e \u0928\u0939\u0940\u0902, \u0907\u0938\u0932\u093f\u090f \u0939\u0930\u0915\u0924 \u0915\u0930\u0928\u0947 \u0938\u0947 \u092a\u0939\u0932\u0947 \u0939\u0940 \u0930\u0941\u0915 \u0938\u0915\u0924\u0947 \u0939\u0948\u0902\u0964 stop-signal \u091f\u093e\u0938\u094d\u0915 \u0906\u092a\u0915\u094b \u0915\u094d\u0930\u093f\u092f\u093e \u0915\u0930\u0928\u0947 \u0915\u094b \u0915\u0939\u0924\u093e \u0939\u0948 \u0914\u0930 \u092b\u093f\u0930, \u090f\u0915 \u092a\u0932 \u092c\u093e\u0926, \u0915\u092d\u0940-\u0915\u092d\u0940 \u0909\u0938\u0947 \u0930\u094b\u0915\u0928\u0947 \u0915\u093e \u0906\u0926\u0947\u0936 \u0926\u0947\u0924\u093e \u0939\u0948 \u2014 \u092f\u0939 \u0909\u0938 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0915\u094b \u0930\u0926\u094d\u0926 \u0915\u0930\u0928\u093e \u092e\u093e\u092a\u0924\u093e \u0939\u0948 \u091c\u094b \u092a\u0939\u0932\u0947 \u0938\u0947 \u0917\u0924\u093f \u092e\u0947\u0902 \u0906 \u091a\u0941\u0915\u0940 \u0939\u0948\u0964 \u092f\u0947 \u0926\u094b\u0928\u094b\u0902 \u091c\u0941\u0921\u093c\u0947 \u0939\u0941\u090f \u0939\u0948\u0902, \u092a\u0930 \u0925\u094b\u0921\u093c\u0947 \u0905\u0932\u0917 \u092c\u094d\u0930\u0947\u0915-\u0932\u0917\u093e\u0928\u0947 \u0935\u093e\u0932\u0947 \u0924\u0902\u0924\u094d\u0930\u094b\u0902 \u0915\u094b \u091b\u0942\u0924\u0947 \u0939\u0948\u0902\u0964"],["\u0915\u094d\u092f\u093e \u0907\u0938\u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u092e\u0941\u091d\u0947 \u0905\u0938\u0932 \u091c\u093c\u093f\u0902\u0926\u0917\u0940 \u092e\u0947\u0902 \u0915\u092e \u0906\u0935\u0947\u0917\u0940 \u092c\u0928\u093e \u0926\u0947\u0917\u093e?","\u0908\u092e\u093e\u0928\u0926\u093e\u0930\u0940 \u0938\u0947 \u0915\u0939\u0947\u0902 \u0924\u094b \u0938\u092c\u0942\u0924 \u092a\u0924\u0932\u0947 \u0939\u0948\u0902\u0964 \u0906\u092a \u0907\u0938 \u091f\u093e\u0938\u094d\u0915 \u092e\u0947\u0902 \u0914\u0930 \u0907\u0938\u0915\u0947 \u092d\u0940\u0924\u0930 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0930\u094b\u0915\u0928\u0947 \u092e\u0947\u0902 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0922\u0902\u0917 \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u090f\u0901\u0917\u0947, \u092a\u0930 \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0947 \u0906\u0935\u0947\u0917-\u0928\u093f\u092f\u0902\u0924\u094d\u0930\u0923 \u092f\u093e \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u0906\u0924\u094d\u092e-\u0905\u0928\u0941\u0936\u093e\u0938\u0928 \u0924\u0915 \u0938\u094d\u0925\u093e\u0928\u093e\u0902\u0924\u0930\u0923 \u0915\u092e\u091c\u093c\u094b\u0930 \u0914\u0930 \u0935\u093f\u0935\u093e\u0926\u093f\u0924 \u0939\u0948\u0964 \u0907\u0938\u0947 \u0932\u0915\u094d\u0937\u093f\u0924 \u0927\u094d\u092f\u093e\u0928-\u0914\u0930-\u0928\u093f\u0930\u094b\u0927 \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0947 \u0924\u094c\u0930 \u092a\u0930 \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0915\u0930\u0947\u0902, \u0906\u0935\u0947\u0917 \u0915\u0947 \u0907\u0932\u093e\u091c \u0915\u0947 \u0924\u094c\u0930 \u092a\u0930 \u0928\u0939\u0940\u0902\u0964"],["\u092e\u0948\u0902 no-go \u0938\u0902\u0915\u0947\u0924\u094b\u0902 \u092a\u0930 \u092c\u093e\u0930-\u092c\u093e\u0930 \u091f\u0948\u092a \u0915\u0930 \u0926\u0947\u0924\u093e \u0939\u0942\u0901\u0964 \u0915\u094d\u092f\u093e \u092e\u0948\u0902 \u0917\u093c\u0932\u0924 \u0915\u0930 \u0930\u0939\u093e \u0939\u0942\u0901?","\u092c\u093f\u0932\u0915\u0941\u0932 \u0928\u0939\u0940\u0902\u0964 \u0935\u0947 \u091a\u0942\u0915\u0947\u0902, \u091c\u093f\u0928\u094d\u0939\u0947\u0902 commission errors \u0915\u0939\u0924\u0947 \u0939\u0948\u0902, \u0907\u0938 \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u093e \u092a\u0942\u0930\u093e \u092e\u0915\u093c\u0938\u0926 \u0939\u0948\u0902 \u0914\u0930 \u092f\u0939\u0940 \u0907\u0938\u0915\u0940 \u0938\u092c\u0938\u0947 \u0905\u0939\u092e \u092e\u093e\u092a \u0939\u0948\u0964 \u0939\u0941\u0928\u0930 \u092f\u0939 \u0939\u0948 \u0915\u093f \u092c\u0938 \u0907\u0924\u0928\u093e \u0927\u0940\u092e\u0947 \u0939\u094b \u091c\u093e\u090f\u0901 \u0915\u093f \u0909\u0928\u094d\u0939\u0947\u0902 \u092a\u0915\u0921\u093c \u0938\u0915\u0947\u0902\u0964 \u0905\u0917\u0930 \u0906\u092a \u0936\u0942\u0928\u094d\u092f \u0917\u093c\u0932\u0924\u093f\u092f\u093e\u0901 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902, \u0924\u094b \u0936\u093e\u092f\u0926 \u0906\u092a \u0907\u0924\u0928\u0947 \u0938\u0924\u0930\u094d\u0915 \u0939\u0948\u0902 \u0915\u093f \u0915\u094b\u0908 \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923-\u092e\u0942\u0932\u094d\u092f \u0939\u0940 \u0928\u0939\u0940\u0902 \u092c\u091a\u0924\u093e\u0964"]],variants:"\u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0907\u0938 \u092c\u093e\u0924 \u0938\u0947 \u0905\u0932\u0917 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902 \u0915\u093f no-go \u0915\u093f\u0924\u0928\u093e \u0926\u0941\u0930\u094d\u0932\u092d \u0939\u0948 \u0914\u0930 \u0938\u0902\u0915\u0947\u0924 \u0915\u094d\u092f\u093e \u0939\u0948\u0902\u0964 SART (Robertson, 1997) \u0905\u0928\u0941\u092a\u093e\u0924 \u0915\u094b \u0909\u0932\u091f \u0926\u0947\u0924\u093e \u0939\u0948, \u0924\u093e\u0915\u093f go \u0932\u0917\u093e\u0924\u093e\u0930 \u0930\u0939\u0947 \u0914\u0930 no-go \u0926\u0941\u0930\u094d\u0932\u092d \u0939\u094b \u091c\u093e\u090f \u2014 \u0907\u0938\u0938\u0947 \u091f\u093f\u0915\u093e\u090a \u0927\u094d\u092f\u093e\u0928 \u092a\u0930 \u091c\u093c\u094b\u0930 \u092a\u0921\u093c\u0924\u093e \u0939\u0948\u0964 \u0905\u0928\u094d\u092f \u0930\u0942\u092a\u093e\u0902\u0924\u0930 \u0916\u093c\u093e\u0938 \u0936\u094d\u0930\u0947\u0923\u093f\u092f\u094b\u0902 \u0915\u094b no-go \u092c\u0928\u093e\u0924\u0947 \u0939\u0948\u0902, \u091c\u0948\u0938\u0947 \u091c\u0902\u0915 \u092b\u093c\u0942\u0921, \u0936\u0930\u093e\u092c \u0915\u0947 \u0938\u0902\u0915\u0947\u0924, \u092f\u093e \u0916\u093c\u093e\u0938 \u092d\u093e\u0935\u0928\u093e\u0924\u094d\u092e\u0915 \u091a\u0947\u0939\u0930\u0947; \u0914\u0930 \u0927\u094d\u092f\u093e\u0928 \u092a\u0930 \u0914\u0930 \u092c\u094b\u091d \u0921\u093e\u0932\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0907\u0938 \u091f\u093e\u0938\u094d\u0915 \u0915\u094b \u0905\u0915\u094d\u0938\u0930 \u092b\u093c\u094d\u0932\u0948\u0902\u0915\u0930 \u092f\u093e visual-search \u0924\u0924\u094d\u0935\u094b\u0902 \u0915\u0947 \u0938\u093e\u0925 \u091c\u094b\u0921\u093c \u0926\u093f\u092f\u093e \u091c\u093e\u0924\u093e \u0939\u0948\u0964"},zh:{about:"\u523a\u6fc0\u4e00\u4e2a\u63a5\u4e00\u4e2a\u5730\u95ea\u73b0\uff0c\u5176\u4e2d\u5927\u591a\u6570\u662f\u201cgo\u201d\u4fe1\u53f7\uff1a\u770b\u5230\u5c31\u5c3d\u5feb\u70b9\u51fb\u3002\u5c11\u6570\u662f\u201cno-go\u201d\u4fe1\u53f7\uff0c\u78b0\u5230\u5b83\u4eec\u4f60\u5fc5\u987b\u5b8c\u5168\u4e0d\u52a8\u3002\u96be\u70b9\u5728\u4e8e\uff0c\u70b9\u51fb\u5728\u51e0\u79d2\u5185\u5c31\u4f1a\u53d8\u6210\u4e60\u60ef\uff0c\u6240\u4ee5\u5728\u201cno-go\u201d\u51fa\u73b0\u65f6\u628a\u624b\u6307\u505c\u4f4f\u9700\u8981\u771f\u6b63\u7684\u52aa\u529b\u3002",benefit:"\u5b83\u8bad\u7ec3\u7684\u662f\u53cd\u5e94\u6291\u5236\u2014\u2014\u4e5f\u5c31\u662f\u53d6\u6d88\u4e00\u4e2a\u4f60\u5df2\u7ecf\u51c6\u5907\u542f\u52a8\u7684\u52a8\u4f5c\u7684\u80fd\u529b\uff0c\u540c\u65f6\u8fd8\u8bad\u7ec3\u4e3a\u6355\u6349\u90a3\u4e2a\u5076\u5c14\u51fa\u73b0\u3001\u8981\u4f60\u201c\u505c\u4e0b\u201d\u7684\u4fe1\u53f7\u6240\u9700\u7684\u6301\u7eed\u6ce8\u610f\u529b\u3002\u7528\u65e5\u5e38\u7684\u8bdd\u8bf4\uff0c\u5b83\u7ec3\u7684\u662f\u81ea\u63a7\u529b\u91cc\u7684\u5239\u8f66\uff0c\u800c\u4e0d\u662f\u6cb9\u95e8\u3002",history:"go/no-go \u8fd9\u79cd\u8bbe\u7f6e\u53ef\u4ee5\u8ffd\u6eaf\u5230 1868 \u5e74\u7684 Franciscus Donders\uff0c\u4ed6\u628a\u5b83\u4f5c\u4e3a\u4e09\u9879\u4efb\u52a1\u4e4b\u4e00\uff0c\u7528\u5728\u81ea\u5df1\u6d4b\u91cf\u5fc3\u7406\u8fc7\u7a0b\u8017\u65f6\u7684\u201c\u51cf\u6cd5\u6cd5\u201d\u91cc\u3002\u6574\u4e2a\u4e8c\u5341\u4e16\u7eaa\uff0c\u5b83\u88ab\u5b9e\u9a8c\u5fc3\u7406\u5b66\u548c\u4e34\u5e8a\u5fc3\u7406\u5b66\u91c7\u7eb3\uff0c\u6210\u4e3a\u63a2\u67e5\u51b2\u52a8\u6027\u548c\u989d\u53f6\u529f\u80fd\u7684\u6807\u51c6\u624b\u6bb5\uff0c\u540e\u6765\u53c8\u6269\u5c55\u5230\u795e\u7ecf\u5f71\u50cf\u5b66\u3001\u591a\u52a8\u75c7\u4e0e\u6210\u763e\u7814\u7a76\uff0c\u4ee5\u53ca\u9762\u5411\u5927\u4f17\u7684\u8111\u529b\u8bad\u7ec3\u5e94\u7528\u4e2d\u3002",creator:"\u5b83\u6ca1\u6709\u5355\u4e00\u7684\u53d1\u660e\u8005\u3002\u8fd9\u4e00\u8303\u5f0f\u901a\u5e38\u8ffd\u6eaf\u5230\u8377\u5170\u751f\u7406\u5b66\u5bb6 Franciscus Cornelis Donders \u53ca\u5176 1868 \u5e74\u5173\u4e8e\u53cd\u5e94\u65f6\u7684\u5de5\u4f5c\uff08\u4ed6\u7684\u201cC \u4efb\u52a1\u201d\uff09\uff0c\u6b64\u540e\u53c8\u7ecf\u8bb8\u591a\u7814\u7a76\u8005\u6539\u826f\u3002\u5b83\u5c5e\u4e8e\u5fc3\u7406\u8ba1\u65f6\u5b66\u8fd9\u4e00\u5b9e\u9a8c\u5fc3\u7406\u5b66\u4f20\u7edf\uff0c\u800c\u4e0d\u5f52\u529f\u4e8e\u67d0\u4e00\u4f4d\u4f5c\u8005\u6216\u67d0\u4e00\u5e74\u4efd\u3002",methods:"\u8ba9\u201cno-go\u201d\u4fe1\u53f7\u4fdd\u6301\u771f\u6b63\u7684\u7a00\u5c11\uff0c\u5927\u7ea6\u56db\u5206\u4e4b\u4e00\u6216\u66f4\u4f4e\uff0c\u56e0\u4e3a\u6b63\u662f\u8fd9\u79cd\u6bd4\u4f8b\u624d\u4f1a\u517b\u6210\u90a3\u4e2a\u4f60\u8981\u53bb\u514b\u5236\u7684\u81ea\u52a8\u51b2\u52a8\u3002\u628a\u8282\u594f\u63a7\u5236\u5728\u8f7b\u677e\u4f46\u504f\u5feb\u7684\u6c34\u5e73\uff0c\u5e76\u628a\u8bef\u89e6\uff08\u5728\u201cno-go\u201d\u4e0a\u70b9\u51fb\uff09\u5f53\u4f5c\u771f\u6b63\u91cd\u8981\u7684\u6210\u7ee9\uff0c\u800c\u4e0d\u662f\u5355\u7eaf\u6c42\u5feb\u3002\u5982\u679c\u4f60\u4ece\u4e0d\u51fa\u9519\uff0c\u8bf4\u660e\u901f\u5ea6\u592a\u6162\u4e86\uff0c\u6240\u4ee5\u628a\u8282\u594f\u5f80\u4e0a\u63a8\u5230\u5f00\u59cb\u51fa\u73b0\u5931\u8bef\uff0c\u7136\u540e\u7a33\u5b9a\u5728\u90a3\u4e2a\u6c34\u5e73\u3002",duration:"\u77ed\u800c\u9891\u7e41\u80dc\u8fc7\u957f\u800c\u7a00\u758f\u3002\u6bcf\u6b21\u4e94\u5230\u5341\u5206\u949f\u3001\u6bcf\u5468\u51e0\u6b21\uff0c\u5c31\u8db3\u591f\u4e86\uff1b\u8fd9\u9879\u4efb\u52a1\u5f88\u8d39\u8111\uff0c\u4e00\u65e6\u6ce8\u610f\u529b\u6da3\u6563\uff0c\u51c6\u786e\u7387\u5c31\u4f1a\u4e0b\u964d\uff0c\u6240\u4ee5\u8981\u8d81\u72b6\u6001\u8fd8\u597d\u65f6\u5c31\u505c\uff0c\u800c\u4e0d\u662f\u786c\u6491\u4e00\u5927\u6bb5\u3002",research:"\u786e\u51ff\u7684\u7ed3\u8bba\u8303\u56f4\u5f88\u7a84\uff1a\u901a\u8fc7\u7ec3\u4e60\uff0c\u4f60\u7684\u8bef\u89e6\u4f1a\u53d8\u5c11\uff0c\u4f60\u5728\u8fd9\u7c7b\u4efb\u52a1\u4e0a\u7684\u6291\u5236\u4f1a\u66f4\u5feb\u3001\u66f4\u5e72\u51c0\u5229\u843d\u3002\u66f4\u5bbd\u6cdb\u7684\u8bf4\u6cd5\u5219\u8981\u5f31\u5f97\u591a\u3002Enge \u53ca\u540c\u4e8b\uff082014\uff09\u7684\u4e00\u9879\u8457\u540d\u8bad\u7ec3\u7814\u7a76\u6ca1\u6709\u53d1\u73b0\u4ee4\u4eba\u4fe1\u670d\u7684\u8bc1\u636e\u8868\u660e\u6291\u5236\u8bad\u7ec3\u80fd\u8fc1\u79fb\u5230\u672a\u7ecf\u8bad\u7ec3\u7684\u80fd\u529b\u4e0a\uff0c\u800c\u5bf9\u6267\u884c\u529f\u80fd\u8bad\u7ec3\u7684\u7efc\u8ff0\u603b\u4f53\u4e0a\u663e\u793a\u8fdc\u8fc1\u79fb\u5f88\u5c11\u3001\u4e5f\u6ca1\u6709\u53ef\u9760\u7684\u667a\u5546\u63d0\u5347\u3002\u9488\u5bf9\u98df\u7269\u7684 go/no-go \u8bad\u7ec3\u786e\u5b9e\u80fd\u5728\u5b9e\u9a8c\u5ba4\u91cc\u53ef\u9760\u5730\u964d\u4f4e\u201cno-go\u201d\u98df\u7269\u7684\u5438\u5f15\u529b\uff0c\u4f46\u8fd9\u662f\u5426\u80fd\u6301\u4e45\u5730\u6539\u53d8\u771f\u5b9e\u7684\u8fdb\u98df\u6216\u996e\u9152\u884c\u4e3a\u4ecd\u6709\u4e89\u8bae\uff0c\u6240\u4ee5\u5bf9\u4efb\u4f55\u8d85\u51fa\u201c\u4f60\u4f1a\u66f4\u64c5\u957f\u8fd9\u9879\u4efb\u52a1\u201d\u7684\u627f\u8bfa\u90fd\u8981\u4fdd\u6301\u8c28\u614e\u3002",rec:"\u76ef\u4f4f\u4f60\u7684\u8bef\u89e6\u7387\uff0c\u800c\u4e0d\u662f\u53cd\u5e94\u65f6\uff1a\u4e00\u573a\u5728\u504f\u5feb\u8282\u594f\u4e0b\u4fdd\u6301\u51c6\u786e\u7684\u8bad\u7ec3\uff0c\u80dc\u8fc7\u4e00\u573a\u901f\u5ea6\u98de\u5feb\u5374\u5931\u8bef\u8fde\u8fde\u7684\u8bad\u7ec3\u3002",faq:[["\u8fd9\u548c\u505c\u6b62\u4fe1\u53f7\u4efb\u52a1\u662f\u4e00\u56de\u4e8b\u5417\uff1f","\u4e0d\u662f\u3002\u5728 go/no-go \u91cc\uff0c\u4f60\u662f\u6839\u636e\u4fe1\u53f7\u672c\u8eab\u6765\u51b3\u5b9a\u8981\u4e0d\u8981\u52a8\u4f5c\uff0c\u6240\u4ee5\u4f60\u53ef\u4ee5\u5728\u52a8\u8d77\u6765\u4e4b\u524d\u5c31\u628a\u52a8\u4f5c\u538b\u4f4f\u3002\u800c\u505c\u6b62\u4fe1\u53f7\u4efb\u52a1\u5148\u8ba9\u4f60\u52a8\u4f5c\uff0c\u8fc7\u4e00\u62cd\u4e4b\u540e\u6709\u65f6\u518d\u547d\u4ee4\u4f60\u4e2d\u6b62\uff0c\u6d4b\u7684\u662f\u53d6\u6d88\u4e00\u4e2a\u5df2\u7ecf\u542f\u52a8\u7684\u53cd\u5e94\u3002\u4e24\u8005\u76f8\u5173\uff0c\u4f46\u89e6\u53ca\u7684\u5239\u8f66\u8fc7\u7a0b\u7565\u6709\u4e0d\u540c\u3002"],["\u7ec3\u8fd9\u4e2a\u4f1a\u8ba9\u6211\u5728\u73b0\u5b9e\u751f\u6d3b\u4e2d\u66f4\u4e0d\u51b2\u52a8\u5417\uff1f","\u8bf4\u5b9e\u8bdd\uff0c\u8bc1\u636e\u5f88\u8584\u5f31\u3002\u4f60\u4f1a\u53ef\u9760\u5730\u5728\u4efb\u52a1\u91cc\u53d8\u5f97\u66f4\u64c5\u957f\u3001\u66f4\u80fd\u538b\u4f4f\u53cd\u5e94\uff0c\u4f46\u80fd\u5426\u8fc1\u79fb\u5230\u65e5\u5e38\u7684\u51b2\u52a8\u63a7\u5236\u6216\u4e00\u822c\u7684\u81ea\u5f8b\u4e0a\uff0c\u5219\u65e2\u5f31\u53c8\u6709\u4e89\u8bae\u3002\u628a\u5b83\u5f53\u4f5c\u9488\u5bf9\u6ce8\u610f\u529b\u548c\u6291\u5236\u7684\u5b9a\u5411\u7ec3\u4e60\uff0c\u800c\u4e0d\u662f\u6cbb\u51b2\u52a8\u7684\u826f\u65b9\u3002"],["\u6211\u8001\u662f\u5728\u201cno-go\u201d\u4fe1\u53f7\u4e0a\u70b9\u4e0b\u53bb\uff0c\u662f\u6211\u505a\u9519\u4e86\u5417\uff1f","\u5b8c\u5168\u4e0d\u662f\u3002\u8fd9\u4e9b\u5931\u8bef\u53eb\u505a\u9519\u8bef\u53cd\u5e94\uff08commission errors\uff09\uff0c\u5b83\u4eec\u6b63\u662f\u8fd9\u9879\u7ec3\u4e60\u7684\u5168\u90e8\u610f\u4e49\u6240\u5728\uff0c\u4e5f\u662f\u5b83\u4e3b\u8981\u6d4b\u91cf\u7684\u4e1c\u897f\u3002\u8bc0\u7a8d\u662f\u628a\u901f\u5ea6\u653e\u6162\u5230\u521a\u597d\u80fd\u6293\u4f4f\u5b83\u4eec\u3002\u5982\u679c\u4f60\u4e00\u4e2a\u9519\u90fd\u4e0d\u72af\uff0c\u90a3\u5f88\u53ef\u80fd\u662f\u4f60\u592a\u8fc7\u5c0f\u5fc3\uff0c\u53cd\u800c\u5f97\u4e0d\u5230\u4efb\u4f55\u8bad\u7ec3\u4ef7\u503c\u3002"]],variants:"\u4e0d\u540c\u7248\u672c\u7684\u5dee\u522b\u5728\u4e8e\u201cno-go\u201d\u6709\u591a\u7a00\u5c11\uff0c\u4ee5\u53ca\u4fe1\u53f7\u662f\u4ec0\u4e48\u3002SART\uff08Robertson\uff0c1997\uff09\u628a\u6bd4\u4f8b\u53cd\u4e86\u8fc7\u6765\uff0c\u8ba9\u201cgo\u201d\u4fdd\u6301\u6052\u5b9a\u3001\u201cno-go\u201d\u53d8\u5f97\u7a00\u5c11\uff0c\u4ece\u800c\u5f3a\u8c03\u6301\u7eed\u6ce8\u610f\u529b\u3002\u5176\u4ed6\u53d8\u4f53\u7528\u7279\u5b9a\u7c7b\u522b\u4f5c\u4e3a\u201cno-go\u201d\uff0c\u6bd4\u5982\u5783\u573e\u98df\u54c1\u3001\u9152\u7cbe\u7ebf\u7d22\u6216\u67d0\u4e9b\u60c5\u7eea\u9762\u5b54\uff0c\u800c\u4e14\u8fd9\u9879\u4efb\u52a1\u5e38\u4e0e flanker \u6216\u89c6\u89c9\u641c\u7d22\u6210\u5206\u7ed3\u5408\uff0c\u4ee5\u8fdb\u4e00\u6b65\u52a0\u91cd\u6ce8\u610f\u8d1f\u8377\u3002"}},hanoi:{ru:{about:"\u0425\u0430\u043d\u043e\u0439\u0441\u043a\u0430\u044f \u0431\u0430\u0448\u043d\u044f - \u0433\u043e\u043b\u043e\u0432\u043e\u043b\u043e\u043c\u043a\u0430 \u0438\u0437 \u0442\u0440\u0451\u0445 \u0441\u0442\u0435\u0440\u0436\u043d\u0435\u0439 \u0438 \u0441\u0442\u043e\u043f\u043a\u0438 \u0434\u0438\u0441\u043a\u043e\u0432 \u0440\u0430\u0437\u043d\u043e\u0433\u043e \u0440\u0430\u0437\u043c\u0435\u0440\u0430. \u041d\u0443\u0436\u043d\u043e \u043f\u0435\u0440\u0435\u043d\u0435\u0441\u0442\u0438 \u0432\u0441\u044e \u0441\u0442\u043e\u043f\u043a\u0443 \u0441 \u043f\u0435\u0440\u0432\u043e\u0433\u043e \u0441\u0442\u0435\u0440\u0436\u043d\u044f \u043d\u0430 \u043f\u043e\u0441\u043b\u0435\u0434\u043d\u0438\u0439, \u043f\u0435\u0440\u0435\u043a\u043b\u0430\u0434\u044b\u0432\u0430\u044f \u043f\u043e \u043e\u0434\u043d\u043e\u043c\u0443 \u0434\u0438\u0441\u043a\u0443 \u0437\u0430 \u0440\u0430\u0437 \u0438 \u043d\u0438\u043a\u043e\u0433\u0434\u0430 \u043d\u0435 \u043a\u043b\u0430\u0434\u044f \u0431\u043e\u043b\u044c\u0448\u0438\u0439 \u0434\u0438\u0441\u043a \u043d\u0430 \u043c\u0435\u043d\u044c\u0448\u0438\u0439.",benefit:"\u0422\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u043f\u043b\u0430\u043d\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u0435 \u0438 \u043c\u044b\u0448\u043b\u0435\u043d\u0438\u0435 \u043e\u0442 \u0446\u0435\u043b\u0438: \u0432\u044b \u0434\u0435\u0440\u0436\u0438\u0442\u0435 \u0432 \u0433\u043e\u043b\u043e\u0432\u0435 \u0438\u0442\u043e\u0433\u043e\u0432\u0443\u044e \u043a\u0430\u0440\u0442\u0438\u043d\u0443 \u0438 \u0432\u044b\u0441\u0442\u0440\u0430\u0438\u0432\u0430\u0435\u0442\u0435 \u043f\u043e\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c \u043f\u0440\u043e\u043c\u0435\u0436\u0443\u0442\u043e\u0447\u043d\u044b\u0445 \u0445\u043e\u0434\u043e\u0432, \u0447\u0442\u043e\u0431\u044b \u043a \u043d\u0435\u0439 \u043f\u0440\u0438\u0439\u0442\u0438. \u041f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438 \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u044e\u0442 \u0435\u0451 \u043a\u0430\u043a \u043a\u043b\u0430\u0441\u0441\u0438\u0447\u0435\u0441\u043a\u0438\u0439 \u0442\u0435\u0441\u0442 \u0443\u043f\u0440\u0430\u0432\u043b\u044f\u044e\u0449\u0438\u0445 \u0444\u0443\u043d\u043a\u0446\u0438\u0439 \u0438 \u043b\u043e\u0431\u043d\u043e\u0433\u043e \u043f\u043b\u0430\u043d\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u044f.",history:"\u041b\u0443\u043a\u0430\u0441 \u0432\u044b\u043f\u0443\u0441\u0442\u0438\u043b \u0433\u043e\u043b\u043e\u0432\u043e\u043b\u043e\u043c\u043a\u0443 \u0432 \u043f\u0440\u043e\u0434\u0430\u0436\u0443 \u0432 1883 \u0433\u043e\u0434\u0443, \u043e\u0431\u0435\u0440\u043d\u0443\u0432 \u0435\u0451 \u0432 \u0432\u044b\u0434\u0443\u043c\u0430\u043d\u043d\u0443\u044e \u043b\u0435\u0433\u0435\u043d\u0434\u0443 \u043e \u0445\u0440\u0430\u043c\u0435, \u0433\u0434\u0435 \u0436\u0440\u0435\u0446\u044b \u043f\u0435\u0440\u0435\u043a\u043b\u0430\u0434\u044b\u0432\u0430\u044e\u0442 64 \u0437\u043e\u043b\u043e\u0442\u044b\u0445 \u0434\u0438\u0441\u043a\u0430, \u0430 \u0441 \u043f\u043e\u0441\u043b\u0435\u0434\u043d\u0438\u043c \u0445\u043e\u0434\u043e\u043c \u044f\u043a\u043e\u0431\u044b \u043d\u0430\u0441\u0442\u0443\u043f\u0430\u0435\u0442 \u043a\u043e\u043d\u0435\u0446 \u0441\u0432\u0435\u0442\u0430. \u0418\u0433\u0440\u0430 \u0431\u044b\u0441\u0442\u0440\u043e \u0440\u0430\u0437\u043e\u0448\u043b\u0430\u0441\u044c \u043a\u0430\u043a \u0441\u0430\u043b\u043e\u043d\u043d\u0430\u044f \u0437\u0430\u0431\u0430\u0432\u0430, \u0430 \u043f\u043e\u0437\u0436\u0435 \u0441\u0442\u0430\u043b\u0430 \u0441\u0442\u0430\u043d\u0434\u0430\u0440\u0442\u043d\u044b\u043c \u0438\u043d\u0441\u0442\u0440\u0443\u043c\u0435\u043d\u0442\u043e\u043c \u0432 \u043c\u0430\u0442\u0435\u043c\u0430\u0442\u0438\u043a\u0435, \u0438\u043d\u0444\u043e\u0440\u043c\u0430\u0442\u0438\u043a\u0435 \u0438 \u043d\u0435\u0439\u0440\u043e\u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u0438.",creator:"\u0413\u043e\u043b\u043e\u0432\u043e\u043b\u043e\u043c\u043a\u0443 \u043f\u0440\u0438\u0434\u0443\u043c\u0430\u043b \u0444\u0440\u0430\u043d\u0446\u0443\u0437\u0441\u043a\u0438\u0439 \u043c\u0430\u0442\u0435\u043c\u0430\u0442\u0438\u043a \u042d\u0434\u0443\u0430\u0440\u0434 \u041b\u044e\u043a\u0430 \u0432 1883 \u0433\u043e\u0434\u0443. \u041f\u0435\u0440\u0432\u044b\u0439 \u043d\u0430\u0431\u043e\u0440 \u043e\u043d \u043f\u0440\u043e\u0434\u0430\u0432\u0430\u043b \u043f\u043e\u0434 \u043f\u0441\u0435\u0432\u0434\u043e\u043d\u0438\u043c\u043e\u043c \"N. Claus (de Siam)\" - \u044d\u0442\u043e \u0430\u043d\u0430\u0433\u0440\u0430\u043c\u043c\u0430 \u043e\u0442 \"Lucas d'Amiens\", \u0442\u043e \u0435\u0441\u0442\u044c \u041b\u044e\u043a\u0430 \u0438\u0437 \u0410\u043c\u044c\u0435\u043d\u0430, \u0435\u0433\u043e \u0440\u043e\u0434\u043d\u043e\u0433\u043e \u0433\u043e\u0440\u043e\u0434\u0430.",methods:"\u0414\u0443\u043c\u0430\u0439\u0442\u0435 \u0440\u0435\u043a\u0443\u0440\u0441\u0438\u0432\u043d\u043e: \u0447\u0442\u043e\u0431\u044b \u043f\u0435\u0440\u0435\u043d\u0435\u0441\u0442\u0438 \u0441\u0442\u043e\u043f\u043a\u0443 \u0438\u0437 N \u0434\u0438\u0441\u043a\u043e\u0432, \u0441\u043d\u0430\u0447\u0430\u043b\u0430 \u043f\u0435\u0440\u0435\u043b\u043e\u0436\u0438\u0442\u0435 \u0432\u0435\u0440\u0445\u043d\u0438\u0435 N-1 \u043d\u0430 \u0437\u0430\u043f\u0430\u0441\u043d\u043e\u0439 \u0441\u0442\u0435\u0440\u0436\u0435\u043d\u044c, \u043f\u0435\u0440\u0435\u0441\u0442\u0430\u0432\u044c\u0442\u0435 \u0441\u0430\u043c\u044b\u0439 \u0431\u043e\u043b\u044c\u0448\u043e\u0439 \u0434\u0438\u0441\u043a, \u0437\u0430\u0442\u0435\u043c \u0432\u0435\u0440\u043d\u0438\u0442\u0435 N-1 \u043e\u0431\u0440\u0430\u0442\u043d\u043e \u0441\u0432\u0435\u0440\u0445\u0443. \u041f\u043b\u0430\u043d\u0438\u0440\u0443\u0439\u0442\u0435 \u043d\u0430 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0445\u043e\u0434\u043e\u0432 \u0432\u043f\u0435\u0440\u0451\u0434, \u0430 \u043d\u0435 \u0445\u0432\u0430\u0442\u0430\u0439\u0442\u0435 \u0431\u043b\u0438\u0436\u0430\u0439\u0448\u0438\u0439 \u0434\u043e\u043f\u0443\u0441\u0442\u0438\u043c\u044b\u0439 \u0445\u043e\u0434; \u043f\u0440\u0438 \u043d\u0435\u0447\u0451\u0442\u043d\u043e\u043c \u0447\u0438\u0441\u043b\u0435 \u0434\u0438\u0441\u043a\u043e\u0432 \u043d\u0430\u0447\u0438\u043d\u0430\u0439\u0442\u0435 \u0441 \u0442\u043e\u0433\u043e, \u0447\u0442\u043e \u0434\u0432\u0438\u0433\u0430\u0435\u0442\u0435 \u0441\u0430\u043c\u044b\u0439 \u043c\u0430\u043b\u0435\u043d\u044c\u043a\u0438\u0439 \u0434\u0438\u0441\u043a \u043a \u0446\u0435\u043b\u0435\u0432\u043e\u043c\u0443 \u0441\u0442\u0435\u0440\u0436\u043d\u044e, \u043c\u0435\u043d\u044f\u044f \u0435\u0433\u043e \u043d\u0430\u043f\u0440\u0430\u0432\u043b\u0435\u043d\u0438\u0435 \u043d\u0430 \u043a\u0430\u0436\u0434\u043e\u043c \u0445\u043e\u0434\u0443.",duration:"\u041b\u0443\u0447\u0448\u0435 \u0440\u0430\u0431\u043e\u0442\u0430\u044e\u0442 \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u0435 \u0441\u043e\u0441\u0440\u0435\u0434\u043e\u0442\u043e\u0447\u0435\u043d\u043d\u044b\u0435 \u043f\u043e\u0434\u0445\u043e\u0434\u044b \u043f\u043e 10-15 \u043c\u0438\u043d\u0443\u0442 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0440\u0430\u0437 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e. \u041a\u0430\u043a \u0442\u043e\u043b\u044c\u043a\u043e \u043d\u0430\u0447\u0430\u043b\u0438 \u0440\u0435\u0448\u0430\u0442\u044c \u0434\u0430\u043d\u043d\u0443\u044e \u0432\u044b\u0441\u043e\u0442\u0443 \u043e\u043f\u0442\u0438\u043c\u0430\u043b\u044c\u043d\u043e - \u0434\u043e\u0431\u0430\u0432\u043b\u044f\u0439\u0442\u0435 \u0434\u0438\u0441\u043a, \u0430 \u043d\u0435 \u043f\u043e\u0432\u0442\u043e\u0440\u044f\u0439\u0442\u0435 \u0442\u0443 \u0436\u0435 \u043b\u0451\u0433\u043a\u0443\u044e \u0432\u044b\u0441\u043e\u0442\u0443.",research:"\u041d\u0430\u0434\u0451\u0436\u043d\u0435\u0435 \u0432\u0441\u0435\u0433\u043e \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u0435\u0442\u0441\u044f \u0440\u043e\u0432\u043d\u043e \u0442\u043e, \u0447\u0435\u0433\u043e \u0438 \u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043b\u043e \u0436\u0434\u0430\u0442\u044c: \u0432\u044b \u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u0435\u0441\u044c \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u0438 \u0442\u043e\u0447\u043d\u0435\u0435 \u0432 \u0441\u0430\u043c\u043e\u0439 \u0433\u043e\u043b\u043e\u0432\u043e\u043b\u043e\u043c\u043a\u0435 \u0438 \u0432 \u0431\u043b\u0438\u0437\u043a\u0438\u0445 \u0437\u0430\u0434\u0430\u0447\u0430\u0445 \u043d\u0430 \u043f\u043b\u0430\u043d\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u0435, \u0438 \u043e\u043d\u0430 \u043e\u0441\u0442\u0430\u0451\u0442\u0441\u044f \u0443\u0432\u0430\u0436\u0430\u0435\u043c\u044b\u043c \u043a\u043b\u0438\u043d\u0438\u0447\u0435\u0441\u043a\u0438\u043c \u0442\u0435\u0441\u0442\u043e\u043c \u044d\u0442\u043e\u0439 \u0441\u043f\u043e\u0441\u043e\u0431\u043d\u043e\u0441\u0442\u0438. \u0428\u0438\u0440\u043e\u043a\u0438\u0435 \u0437\u0430\u044f\u0432\u043b\u0435\u043d\u0438\u044f, \u0431\u0443\u0434\u0442\u043e \u043e\u043d\u0430 \u043f\u043e\u0434\u043d\u0438\u043c\u0430\u0435\u0442 \u043e\u0431\u0449\u0438\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0438\u043b\u0438 \u043f\u043e\u0432\u0441\u0435\u0434\u043d\u0435\u0432\u043d\u0443\u044e \u0441\u043e\u043e\u0431\u0440\u0430\u0437\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c, \u043a\u0443\u0434\u0430 \u0441\u043b\u0430\u0431\u0435\u0435 - \u043e\u0431\u0437\u043e\u0440\u044b \u0442\u0440\u0435\u043d\u0430\u0436\u0451\u0440\u043e\u0432 \u0434\u043b\u044f \u043c\u043e\u0437\u0433\u0430 \u0440\u0430\u0437 \u0437\u0430 \u0440\u0430\u0437\u043e\u043c \u043d\u0435 \u043d\u0430\u0445\u043e\u0434\u044f\u0442 \u043d\u0430\u0434\u0451\u0436\u043d\u043e\u0433\u043e \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0430 \u043d\u0430 \u043d\u0435\u0441\u0432\u044f\u0437\u0430\u043d\u043d\u044b\u0435 \u0437\u0430\u0434\u0430\u0447\u0438, \u0442\u0430\u043a \u0447\u0442\u043e \u043a \u0433\u0440\u043e\u043c\u043a\u0438\u043c \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f\u043c \u0441\u0442\u043e\u0438\u0442 \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u044c\u0441\u044f \u0441 \u043e\u0441\u0442\u043e\u0440\u043e\u0436\u043d\u043e\u0441\u0442\u044c\u044e.",rec:"\u041f\u043e\u0441\u043b\u0435 \u043a\u0430\u0436\u0434\u043e\u0433\u043e \u0440\u0435\u0448\u0435\u043d\u0438\u044f \u043f\u0440\u043e\u0438\u0433\u0440\u0430\u0439\u0442\u0435 \u043f\u0430\u0440\u0442\u0438\u044e \u0432 \u0433\u043e\u043b\u043e\u0432\u0435 \u0438 \u0441\u043f\u0440\u043e\u0441\u0438\u0442\u0435 \u0441\u0435\u0431\u044f, \u0431\u044b\u043b \u043b\u0438 \u043f\u0443\u0442\u044c \u043a\u043e\u0440\u043e\u0447\u0435 - \u0440\u0430\u0437\u0431\u043e\u0440 \u0441\u043e\u0431\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0445 \u0445\u043e\u0434\u043e\u0432 \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u043f\u043b\u0430\u043d\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u0435 \u0441\u0438\u043b\u044c\u043d\u0435\u0435, \u0447\u0435\u043c \u0441\u043b\u0435\u043f\u043e\u0435 \u043f\u043e\u0432\u0442\u043e\u0440\u0435\u043d\u0438\u0435.",faq:[["\u0412\u0441\u0435\u0433\u0434\u0430 \u043b\u0438 \u0435\u0441\u0442\u044c \u043d\u0430\u0438\u043b\u0443\u0447\u0448\u0435\u0435 \u0440\u0435\u0448\u0435\u043d\u0438\u0435?","\u0414\u0430. \u0414\u043b\u044f \u043b\u044e\u0431\u043e\u0433\u043e \u0447\u0438\u0441\u043b\u0430 \u0434\u0438\u0441\u043a\u043e\u0432 \u0435\u0441\u0442\u044c \u0435\u0434\u0438\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0435 \u043a\u0440\u0430\u0442\u0447\u0430\u0439\u0448\u0435\u0435 \u0440\u0435\u0448\u0435\u043d\u0438\u0435, \u0438 \u043e\u043d\u043e \u0437\u0430\u043d\u0438\u043c\u0430\u0435\u0442 \u0434\u0432\u0430 \u0432 \u0441\u0442\u0435\u043f\u0435\u043d\u0438 N \u043c\u0438\u043d\u0443\u0441 \u043e\u0434\u0438\u043d \u0445\u043e\u0434\u043e\u0432: 7 \u0445\u043e\u0434\u043e\u0432 \u0434\u043b\u044f 3 \u0434\u0438\u0441\u043a\u043e\u0432 \u0438 1023 \u0434\u043b\u044f 10."],["\u0421\u0442\u0430\u043d\u0435\u0442 \u043b\u0438 \u043e\u0442 \u044d\u0442\u043e\u0433\u043e \u0433\u043e\u043b\u043e\u0432\u0430 \u0440\u0430\u0431\u043e\u0442\u0430\u0442\u044c \u043b\u0443\u0447\u0448\u0435 \u0432 \u0446\u0435\u043b\u043e\u043c?","\u0427\u0435\u0441\u0442\u043d\u043e - \u0432\u0440\u044f\u0434 \u043b\u0438 \u0432 \u0448\u0438\u0440\u043e\u043a\u043e\u043c \u0441\u043c\u044b\u0441\u043b\u0435. \u0412 \u0441\u0430\u043c\u043e\u0439 \u0433\u043e\u043b\u043e\u0432\u043e\u043b\u043e\u043c\u043a\u0435 \u0438 \u043f\u043e\u0445\u043e\u0436\u0438\u0445 \u0437\u0430\u0434\u0430\u0447\u0430\u0445 \u043d\u0430 \u043f\u043b\u0430\u043d\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u0435 \u0432\u044b \u0437\u0430\u043c\u0435\u0442\u043d\u043e \u043f\u0440\u0438\u0431\u0430\u0432\u0438\u0442\u0435, \u043d\u043e \u0434\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432, \u0447\u0442\u043e \u044d\u0442\u043e \u043f\u043e\u0432\u044b\u0448\u0430\u0435\u0442 \u043e\u0431\u0449\u0438\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0438\u043b\u0438 \u043d\u0435\u0441\u0432\u044f\u0437\u0430\u043d\u043d\u044b\u0435 \u0431\u044b\u0442\u043e\u0432\u044b\u0435 \u043d\u0430\u0432\u044b\u043a\u0438, \u043c\u0430\u043b\u043e."],["\u041f\u043e\u0447\u0435\u043c\u0443 \u044f \u043f\u043e\u0441\u0442\u043e\u044f\u043d\u043d\u043e \u0437\u0430\u0441\u0442\u0440\u0435\u0432\u0430\u044e \u0431\u043b\u0438\u0436\u0435 \u043a \u043a\u043e\u043d\u0446\u0443?","\u041e\u0431\u044b\u0447\u043d\u043e \u043f\u043e\u0442\u043e\u043c\u0443, \u0447\u0442\u043e \u0445\u043e\u0434 \u0441\u0434\u0435\u043b\u0430\u043d \u0431\u0435\u0437 \u043f\u043b\u0430\u043d\u0430. \u041f\u043e\u043f\u0440\u043e\u0431\u0443\u0439\u0442\u0435 \u0438\u0434\u0442\u0438 \u043e\u0442 \u0446\u0435\u043b\u0438 \u043d\u0430\u0437\u0430\u0434 \u0438 \u043c\u044b\u0441\u043b\u0438\u0442\u044c \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u043e\u043c \u0446\u0435\u043b\u044b\u0445 \u043f\u043e\u0434\u0441\u0442\u043e\u043f\u043e\u043a, \u0430 \u043d\u0435 \u043e\u0442\u0434\u0435\u043b\u044c\u043d\u044b\u0445 \u0434\u0438\u0441\u043a\u043e\u0432 - \u0438\u043c\u0435\u043d\u043d\u043e \u044d\u0442\u043e\u0442 \u0440\u0435\u043a\u0443\u0440\u0441\u0438\u0432\u043d\u044b\u0439 \u043f\u0440\u0438\u0451\u043c \u0432\u0441\u0451 \u0441\u0442\u0430\u0432\u0438\u0442 \u043d\u0430 \u043c\u0435\u0441\u0442\u0430."]],variants:"\u0427\u0430\u0449\u0435 \u0432\u0441\u0435\u0433\u043e \u043c\u0435\u043d\u044f\u044e\u0442 \u0447\u0438\u0441\u043b\u043e \u0434\u0438\u0441\u043a\u043e\u0432 (\u043c\u0438\u043d\u0438\u043c\u0443\u043c \u0445\u043e\u0434\u043e\u0432 \u0432\u0441\u0435\u0433\u0434\u0430 \u0440\u0430\u0432\u0435\u043d \u0434\u0432\u0430 \u0432 \u0441\u0442\u0435\u043f\u0435\u043d\u0438 N \u043c\u0438\u043d\u0443\u0441 \u043e\u0434\u0438\u043d), \u0434\u043e\u0431\u0430\u0432\u043b\u044f\u044e\u0442 \u0447\u0435\u0442\u0432\u0451\u0440\u0442\u044b\u0439 \u0441\u0442\u0435\u0440\u0436\u0435\u043d\u044c (\u0433\u043e\u043b\u043e\u0432\u043e\u043b\u043e\u043c\u043a\u0430 \u0420\u0438\u0432\u0430) \u0438\u043b\u0438 \u0432\u0432\u043e\u0434\u044f\u0442 \u0434\u043e\u043f\u043e\u043b\u043d\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0435 \u043f\u0440\u0430\u0432\u0438\u043b\u0430, \u043d\u0430\u043f\u0440\u0438\u043c\u0435\u0440 \u043f\u0435\u0440\u0435\u043a\u043b\u0430\u0434\u044b\u0432\u0430\u0442\u044c \u0434\u0438\u0441\u043a\u0438 \u0442\u043e\u043b\u044c\u043a\u043e \u043c\u0435\u0436\u0434\u0443 \u0441\u043e\u0441\u0435\u0434\u043d\u0438\u043c\u0438 \u0441\u0442\u0435\u0440\u0436\u043d\u044f\u043c\u0438. \u0418\u0437 \u0440\u043e\u0434\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0445 \u0437\u0430\u0434\u0430\u0447 \u043d\u0430 \u043f\u043b\u0430\u043d\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u0435 - \u041b\u043e\u043d\u0434\u043e\u043d\u0441\u043a\u0430\u044f \u0431\u0430\u0448\u043d\u044f, \u043a\u043e\u0442\u043e\u0440\u0443\u044e \u0448\u0438\u0440\u043e\u043a\u043e \u043f\u0440\u0438\u043c\u0435\u043d\u044f\u044e\u0442 \u0432 \u043a\u043e\u0433\u043d\u0438\u0442\u0438\u0432\u043d\u043e\u043c \u0442\u0435\u0441\u0442\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u0438."},en:{about:"The Tower of Hanoi is a puzzle with three pegs and a stack of different-sized disks. Your job is to move the whole stack from the first peg to the last, one disk at a time, never placing a larger disk on top of a smaller one.",benefit:"It trains planning ahead and goal-directed thinking: you have to hold the end state in mind and work out a sequence of sub-moves to reach it. Psychologists use it as a classic measure of executive function and frontal-lobe planning.",history:"Lucas sold it commercially in 1883 wrapped in a fake legend about a temple where priests move 64 golden disks, and the world supposedly ends when they finish. The puzzle spread quickly as a parlour game and later became a standard tool in mathematics, computer science, and neuropsychology.",creator:"It was invented by the French mathematician Edouard Lucas in 1883, who first sold it under the pen name \"N. Claus (de Siam)\" - an anagram of \"Lucas d'Amiens\", his home town.",methods:"Think recursively: to move a stack of N disks, first move the top N-1 onto the spare peg, shift the biggest disk across, then move the N-1 back on top. Plan a few moves ahead rather than grabbing the nearest legal move, and for an odd number of disks start by sending the smallest disk toward the target peg, alternating its direction each turn.",duration:"Short, focused sessions of 10 to 15 minutes work best, a few times a week. Once you can solve a given height optimally, add a disk rather than repeating the same easy size.",research:"The evidence is strongest for exactly what you would expect: you get faster and more accurate at the puzzle itself and at closely related planning tasks, and it remains a respected clinical measure of planning ability. Broad claims that it lifts general intelligence or everyday problem-solving are far weaker - reviews of brain training repeatedly find little reliable far transfer, so treat the grand promises with caution.",rec:"After each solve, replay it in your head and ask whether a shorter path existed - reflection on your own moves trains the planning more than blind repetition.",faq:[["Is there always a best solution?","Yes. For any number of disks there is a single shortest solution, and it takes 2 to the power N minus 1 moves - 7 moves for 3 disks, 1023 for 10."],["Will it make me smarter overall?","Honestly, probably not in a broad sense. You will get clearly better at this puzzle and similar planning tasks, but evidence that it boosts general intelligence or unrelated everyday skills is weak."],["Why do I keep getting stuck near the end?","Usually because you moved without a plan. Try working backward from the goal and think in terms of moving whole sub-stacks, not single disks - that is the recursive trick that makes it click."]],variants:"Common variations change the disk count (the minimum number of moves is always 2 to the power N, minus 1), add a fourth peg (the Reve's puzzle), or impose extra rules such as only moving disks between adjacent pegs. Related planning puzzles include the Tower of London, which is widely used in cognitive testing."},es:{about:"La Torre de Han\xf3i es un rompecabezas con tres varillas y una pila de discos de distintos tama\xf1os. Tu tarea es mover toda la pila desde la primera varilla hasta la \xfaltima, de disco en disco, sin colocar nunca un disco m\xe1s grande sobre uno m\xe1s peque\xf1o.",benefit:"Entrena la planificaci\xf3n anticipada y el pensamiento orientado a metas: tienes que mantener en la mente el estado final y elaborar una secuencia de sub-movimientos para alcanzarlo. Los psic\xf3logos lo usan como una medida cl\xe1sica de la funci\xf3n ejecutiva y de la planificaci\xf3n del l\xf3bulo frontal.",history:"Lucas lo vendi\xf3 comercialmente en 1883 envuelto en una leyenda falsa sobre un templo donde unos sacerdotes mueven 64 discos de oro, y se supone que el mundo termina cuando acaban. El rompecabezas se difundi\xf3 r\xe1pido como juego de sal\xf3n y m\xe1s tarde se convirti\xf3 en una herramienta est\xe1ndar en matem\xe1ticas, inform\xe1tica y neuropsicolog\xeda.",creator:"Fue inventado por el matem\xe1tico franc\xe9s \xc9douard Lucas en 1883, quien primero lo vendi\xf3 bajo el seud\xf3nimo \"N. Claus (de Siam)\", un anagrama de \"Lucas d'Amiens\", su ciudad natal.",methods:"Piensa de forma recursiva: para mover una pila de N discos, mueve primero los N-1 de arriba a la varilla libre, pasa el disco m\xe1s grande al otro lado, y luego vuelve a colocar encima los N-1. Planifica unos cuantos movimientos por adelantado en lugar de agarrar el movimiento legal m\xe1s cercano, y para un n\xfamero impar de discos empieza enviando el disco m\xe1s peque\xf1o hacia la varilla de destino, alternando su direcci\xf3n en cada turno.",duration:"Las sesiones cortas y concentradas de 10 a 15 minutos funcionan mejor, varias veces por semana. Una vez que puedas resolver una altura dada de forma \xf3ptima, a\xf1ade un disco en lugar de repetir el mismo tama\xf1o f\xe1cil.",research:"La evidencia es m\xe1s s\xf3lida justo en lo que cabr\xeda esperar: te vuelves m\xe1s r\xe1pido y preciso en el propio rompecabezas y en tareas de planificaci\xf3n estrechamente relacionadas, y sigue siendo una respetada medida cl\xednica de la capacidad de planificaci\xf3n. Las afirmaciones amplias de que eleva la inteligencia general o la resoluci\xf3n de problemas cotidianos son mucho m\xe1s d\xe9biles: las revisiones del entrenamiento cerebral encuentran una y otra vez poca transferencia lejana fiable, as\xed que toma las grandes promesas con cautela.",rec:"Despu\xe9s de cada soluci\xf3n, vuelve a recorrerla en tu cabeza y preg\xfantate si exist\xeda un camino m\xe1s corto: reflexionar sobre tus propios movimientos entrena la planificaci\xf3n m\xe1s que la repetici\xf3n ciega.",faq:[["\xbfSiempre hay una mejor soluci\xf3n?","S\xed. Para cualquier n\xfamero de discos existe una \xfanica soluci\xf3n m\xe1s corta, y requiere 2 elevado a N menos 1 movimientos: 7 movimientos para 3 discos, 1023 para 10."],["\xbfMe har\xe1 m\xe1s inteligente en general?","Honestamente, probablemente no en un sentido amplio. Mejorar\xe1s claramente en este rompecabezas y en tareas de planificaci\xf3n similares, pero la evidencia de que aumenta la inteligencia general o habilidades cotidianas no relacionadas es d\xe9bil."],["\xbfPor qu\xe9 me quedo atascado cerca del final?","Normalmente porque te moviste sin un plan. Prueba a trabajar hacia atr\xe1s desde la meta y a pensar en t\xe9rminos de mover sub-pilas enteras, no discos sueltos: ese es el truco recursivo que hace que encaje todo."]],variants:"Las variaciones habituales cambian el n\xfamero de discos (el n\xfamero m\xednimo de movimientos es siempre 2 elevado a N, menos 1), a\xf1aden una cuarta varilla (el rompecabezas de Reve) o imponen reglas extra, como mover discos solo entre varillas adyacentes. Entre los rompecabezas de planificaci\xf3n relacionados est\xe1 la Torre de Londres, muy usada en las pruebas cognitivas."},de:{about:"Der Turm von Hanoi ist ein Knobelspiel mit drei St\xe4ben und einem Stapel unterschiedlich gro\xdfer Scheiben. Deine Aufgabe ist es, den ganzen Stapel vom ersten auf den letzten Stab zu bewegen, jeweils eine Scheibe nach der anderen, ohne je eine gr\xf6\xdfere Scheibe auf eine kleinere zu legen.",benefit:"Es trainiert das vorausschauende Planen und zielgerichtete Denken: Du musst den Endzustand im Kopf behalten und eine Folge von Teilz\xfcgen ausarbeiten, um ihn zu erreichen. Psychologen nutzen es als klassisches Ma\xdf f\xfcr die exekutiven Funktionen und die Planungsleistung des Frontallappens.",history:"Lucas verkaufte es 1883 kommerziell, eingeh\xfcllt in eine erfundene Legende \xfcber einen Tempel, in dem Priester 64 goldene Scheiben bewegen und die Welt angeblich endet, wenn sie fertig sind. Das Knobelspiel verbreitete sich rasch als Gesellschaftsspiel und wurde sp\xe4ter zu einem Standardwerkzeug in der Mathematik, der Informatik und der Neuropsychologie.",creator:"Es wurde 1883 vom franz\xf6sischen Mathematiker \xc9douard Lucas erfunden, der es zun\xe4chst unter dem Pseudonym \"N. Claus (de Siam)\" verkaufte \u2013 ein Anagramm von \"Lucas d'Amiens\", seiner Heimatstadt.",methods:"Denke rekursiv: Um einen Stapel von N Scheiben zu bewegen, verschiebe zuerst die oberen N-1 auf den freien Stab, schiebe die gr\xf6\xdfte Scheibe hin\xfcber und bewege dann die N-1 wieder obenauf. Plane einige Z\xfcge voraus, statt nach dem n\xe4chstbesten erlaubten Zug zu greifen, und schicke bei einer ungeraden Anzahl von Scheiben zu Beginn die kleinste Scheibe in Richtung Zielstab und wechsle bei jedem Zug ihre Richtung.",duration:"Kurze, konzentrierte Einheiten von 10 bis 15 Minuten funktionieren am besten, ein paar Mal pro Woche. Sobald du eine bestimmte H\xf6he optimal l\xf6sen kannst, f\xfcge eine Scheibe hinzu, statt dieselbe leichte Gr\xf6\xdfe zu wiederholen.",research:"Am st\xe4rksten ist die Beleglage genau f\xfcr das, was man erwarten w\xfcrde: Du wirst beim Knobelspiel selbst und bei eng verwandten Planungsaufgaben schneller und genauer, und es bleibt ein angesehenes klinisches Ma\xdf f\xfcr die Planungsf\xe4higkeit. Weitreichende Behauptungen, es hebe die allgemeine Intelligenz oder das allt\xe4gliche Probleml\xf6sen, sind weitaus schw\xe4cher belegt \u2013 \xdcbersichtsarbeiten zum Gehirntraining finden immer wieder kaum zuverl\xe4ssigen Ferntransfer, nimm die gro\xdfen Versprechen also mit Vorsicht.",rec:"Spiele jede L\xf6sung danach im Kopf noch einmal durch und frage dich, ob ein k\xfcrzerer Weg m\xf6glich gewesen w\xe4re \u2013 das Nachdenken \xfcber die eigenen Z\xfcge trainiert das Planen mehr als blindes Wiederholen.",faq:[["Gibt es immer eine beste L\xf6sung?","Ja. F\xfcr jede Scheibenzahl gibt es eine einzige k\xfcrzeste L\xf6sung, und sie ben\xf6tigt 2 hoch N minus 1 Z\xfcge \u2013 7 Z\xfcge bei 3 Scheiben, 1023 bei 10."],["Macht es mich insgesamt kl\xfcger?","Ehrlich gesagt wahrscheinlich nicht im breiten Sinn. Du wirst bei diesem Knobelspiel und bei \xe4hnlichen Planungsaufgaben deutlich besser, aber Belege, dass es die allgemeine Intelligenz oder unabh\xe4ngige Alltagsf\xe4higkeiten steigert, sind schwach."],["Warum bleibe ich gegen Ende immer wieder stecken?","Meist, weil du ohne Plan gezogen hast. Versuche, vom Ziel her r\xfcckw\xe4rts zu arbeiten, und denke in ganzen Teilstapeln statt in einzelnen Scheiben \u2013 das ist der rekursive Kniff, der den Knoten platzen l\xe4sst."]],variants:"G\xe4ngige Varianten ver\xe4ndern die Scheibenzahl (die minimale Zugzahl ist stets 2 hoch N minus 1), f\xfcgen einen vierten Stab hinzu (das Reve-Puzzle) oder f\xfchren zus\xe4tzliche Regeln ein, etwa dass Scheiben nur zwischen benachbarten St\xe4ben bewegt werden d\xfcrfen. Zu den verwandten Planungsknobeleien geh\xf6rt der Turm von London, der in der kognitiven Diagnostik weit verbreitet ist."},pt:{about:"A Torre de Han\xf3i \xe9 um quebra-cabe\xe7a com tr\xeas pinos e uma pilha de discos de tamanhos diferentes. A sua tarefa \xe9 mover a pilha inteira do primeiro pino para o \xfaltimo, um disco de cada vez, sem nunca colocar um disco maior sobre um menor.",benefit:"Ele treina o planejamento antecipado e o pensamento orientado a objetivos: voc\xea precisa manter o estado final em mente e descobrir uma sequ\xeancia de sub-jogadas para chegar at\xe9 ele. Os psic\xf3logos o usam como uma medida cl\xe1ssica de fun\xe7\xe3o executiva e de planejamento do lobo frontal.",history:"Lucas o vendeu comercialmente em 1883, embrulhado numa lenda falsa sobre um templo onde sacerdotes movem 64 discos de ouro, e o mundo supostamente acaba quando eles terminam. O quebra-cabe\xe7a se espalhou r\xe1pido como jogo de sal\xe3o e mais tarde se tornou uma ferramenta padr\xe3o na matem\xe1tica, na ci\xeancia da computa\xe7\xe3o e na neuropsicologia.",creator:"Foi inventado pelo matem\xe1tico franc\xeas \xc9douard Lucas em 1883, que o vendeu pela primeira vez sob o pseud\xf4nimo \"N. Claus (de Siam)\" \u2014 um anagrama de \"Lucas d'Amiens\", a sua cidade natal.",methods:"Pense de forma recursiva: para mover uma pilha de N discos, primeiro mova os N-1 de cima para o pino sobressalente, passe o maior disco para o destino e ent\xe3o mova os N-1 de volta por cima. Planeje algumas jogadas \xe0 frente, em vez de pegar a jogada legal mais pr\xf3xima, e, para um n\xfamero \xedmpar de discos, comece enviando o menor disco em dire\xe7\xe3o ao pino-alvo, alternando a sua dire\xe7\xe3o a cada turno.",duration:"Sess\xf5es curtas e concentradas de 10 a 15 minutos funcionam melhor, algumas vezes por semana. Quando voc\xea j\xe1 conseguir resolver uma dada altura de forma \xf3tima, acrescente um disco, em vez de repetir o mesmo tamanho f\xe1cil.",research:"As evid\xeancias s\xe3o mais fortes exatamente para o que se espera: voc\xea fica mais r\xe1pido e mais preciso no pr\xf3prio quebra-cabe\xe7a e em tarefas de planejamento bem relacionadas, e ele continua sendo uma medida cl\xednica respeitada da capacidade de planejamento. Alega\xe7\xf5es amplas de que ele eleva a intelig\xeancia geral ou a resolu\xe7\xe3o de problemas do dia a dia s\xe3o bem mais fr\xe1geis \u2014 revis\xf5es de treino cerebral encontram repetidamente pouca transfer\xeancia distante confi\xe1vel, ent\xe3o encare as grandes promessas com cautela.",rec:"Depois de cada solu\xe7\xe3o, repasse-a mentalmente e pergunte-se se existia um caminho mais curto \u2014 refletir sobre as pr\xf3prias jogadas treina mais o planejamento do que a repeti\xe7\xe3o cega.",faq:[["Sempre existe uma solu\xe7\xe3o \xf3tima?","Sim. Para qualquer n\xfamero de discos h\xe1 uma \xfanica solu\xe7\xe3o mais curta, e ela leva 2 elevado a N menos 1 jogadas \u2014 7 jogadas para 3 discos, 1023 para 10."],["Isso vai me deixar mais inteligente no geral?","Honestamente, provavelmente n\xe3o num sentido amplo. Voc\xea vai ficar claramente melhor neste quebra-cabe\xe7a e em tarefas de planejamento semelhantes, mas as evid\xeancias de que ele aumenta a intelig\xeancia geral ou habilidades do dia a dia n\xe3o relacionadas s\xe3o fr\xe1geis."],["Por que fico travado perto do fim?","Em geral porque voc\xea jogou sem um plano. Tente trabalhar de tr\xe1s para frente a partir do objetivo e pense em termos de mover sub-pilhas inteiras, e n\xe3o discos isolados \u2014 \xe9 esse o truque recursivo que faz a coisa fazer sentido."]],variants:"Varia\xe7\xf5es comuns mudam o n\xfamero de discos (o n\xfamero m\xednimo de jogadas \xe9 sempre 2 elevado a N, menos 1), acrescentam um quarto pino (o quebra-cabe\xe7a de Reve) ou imp\xf5em regras extras, como s\xf3 mover discos entre pinos adjacentes. Quebra-cabe\xe7as de planejamento relacionados incluem a Torre de Londres, amplamente usada em testes cognitivos."},hi:{about:"Tower of Hanoi \u090f\u0915 \u092a\u0939\u0947\u0932\u0940 \u0939\u0948 \u091c\u093f\u0938\u092e\u0947\u0902 \u0924\u0940\u0928 \u0916\u0942\u0901\u091f\u093f\u092f\u093e\u0901 \u0914\u0930 \u0905\u0932\u0917-\u0905\u0932\u0917 \u0906\u0915\u093e\u0930 \u0915\u0940 \u091a\u0915\u0924\u093f\u092f\u094b\u0902 \u0915\u093e \u090f\u0915 \u0922\u0947\u0930 \u0939\u094b\u0924\u093e \u0939\u0948\u0964 \u0906\u092a\u0915\u093e \u0915\u093e\u092e \u0939\u0948 \u092a\u0942\u0930\u0947 \u0922\u0947\u0930 \u0915\u094b \u092a\u0939\u0932\u0940 \u0916\u0942\u0901\u091f\u0940 \u0938\u0947 \u0906\u0916\u093c\u093f\u0930\u0940 \u0916\u0942\u0901\u091f\u0940 \u0924\u0915 \u0932\u0947 \u091c\u093e\u0928\u093e, \u090f\u0915 \u092c\u093e\u0930 \u092e\u0947\u0902 \u090f\u0915 \u091a\u0915\u0924\u0940, \u0914\u0930 \u0915\u092d\u0940 \u092d\u0940 \u0915\u093f\u0938\u0940 \u091b\u094b\u091f\u0940 \u091a\u0915\u0924\u0940 \u0915\u0947 \u090a\u092a\u0930 \u092c\u0921\u093c\u0940 \u091a\u0915\u0924\u0940 \u0928 \u0930\u0916\u0928\u093e\u0964",benefit:"\u092f\u0939 \u0906\u0917\u0947 \u0915\u0940 \u092f\u094b\u091c\u0928\u093e \u092c\u0928\u093e\u0928\u0947 \u0914\u0930 \u0932\u0915\u094d\u0937\u094d\u092f-\u0915\u0947\u0902\u0926\u094d\u0930\u093f\u0924 \u0938\u094b\u091a \u0915\u094b \u0938\u0927\u093e\u0924\u093e \u0939\u0948: \u0906\u092a\u0915\u094b \u0905\u0902\u0924\u093f\u092e \u0938\u094d\u0925\u093f\u0924\u093f \u0915\u094b \u092e\u0928 \u092e\u0947\u0902 \u0925\u093e\u092e\u0915\u0930 \u0909\u0938 \u0924\u0915 \u092a\u0939\u0941\u0901\u091a\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0909\u092a-\u091a\u093e\u0932\u094b\u0902 \u0915\u093e \u090f\u0915 \u0915\u094d\u0930\u092e \u0928\u093f\u0915\u093e\u0932\u0928\u093e \u0939\u094b\u0924\u093e \u0939\u0948\u0964 \u092e\u0928\u094b\u0935\u0948\u091c\u094d\u091e\u093e\u0928\u093f\u0915 \u0907\u0938\u0947 \u0915\u093e\u0930\u094d\u092f\u0915\u093e\u0930\u0940 \u0915\u093e\u0930\u094d\u092f\u092a\u094d\u0930\u0923\u093e\u0932\u0940 \u0914\u0930 \u0905\u0917\u094d\u0930-\u092e\u0938\u094d\u0924\u093f\u0937\u094d\u0915 \u0915\u0940 \u092f\u094b\u091c\u0928\u093e-\u0915\u094d\u0937\u092e\u0924\u093e \u0915\u0940 \u090f\u0915 \u0915\u094d\u0932\u093e\u0938\u093f\u0915 \u092e\u093e\u092a \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902\u0964",history:"Lucas \u0928\u0947 \u0907\u0938\u0947 1883 \u092e\u0947\u0902 \u090f\u0915 \u091d\u0942\u0920\u0940 \u0915\u093f\u0902\u0935\u0926\u0902\u0924\u0940 \u092e\u0947\u0902 \u0932\u092a\u0947\u091f\u0915\u0930 \u0935\u094d\u092f\u093e\u0935\u0938\u093e\u092f\u093f\u0915 \u0930\u0942\u092a \u0938\u0947 \u092c\u0947\u091a\u093e \u2014 \u090f\u0915 \u0910\u0938\u0947 \u092e\u0902\u0926\u093f\u0930 \u0915\u0940 \u0915\u0939\u093e\u0928\u0940 \u091c\u0939\u093e\u0901 \u092a\u0941\u091c\u093e\u0930\u0940 64 \u0938\u0941\u0928\u0939\u0930\u0940 \u091a\u0915\u0924\u093f\u092f\u093e\u0901 \u0939\u093f\u0932\u093e\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u091c\u092c \u0935\u0947 \u092a\u0942\u0930\u093e \u0915\u0930 \u0932\u0947\u0902\u0917\u0947 \u0924\u092c \u0915\u0925\u093f\u0924 \u0924\u094c\u0930 \u092a\u0930 \u0926\u0941\u0928\u093f\u092f\u093e \u0916\u093c\u0924\u094d\u092e \u0939\u094b \u091c\u093e\u090f\u0917\u0940\u0964 \u092f\u0939 \u092a\u0939\u0947\u0932\u0940 \u090f\u0915 \u092c\u0948\u0920\u0915-\u0916\u0947\u0932 \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u0924\u0947\u091c\u093c\u0940 \u0938\u0947 \u092b\u0948\u0932\u0940 \u0914\u0930 \u092c\u093e\u0926 \u092e\u0947\u0902 \u0917\u0923\u093f\u0924, \u0915\u0902\u092a\u094d\u092f\u0942\u091f\u0930 \u0935\u093f\u091c\u094d\u091e\u093e\u0928 \u0914\u0930 \u0924\u0902\u0924\u094d\u0930\u093f\u0915\u093e-\u092e\u0928\u094b\u0935\u093f\u091c\u094d\u091e\u093e\u0928 \u092e\u0947\u0902 \u090f\u0915 \u092e\u093e\u0928\u0915 \u0909\u092a\u0915\u0930\u0923 \u092c\u0928 \u0917\u0908\u0964",creator:"\u0907\u0938\u0947 \u092b\u093c\u094d\u0930\u093e\u0902\u0938\u0940\u0938\u0940 \u0917\u0923\u093f\u0924\u091c\u094d\u091e Edouard Lucas \u0928\u0947 1883 \u092e\u0947\u0902 \u092c\u0928\u093e\u092f\u093e \u0925\u093e, \u091c\u093f\u0928\u094d\u0939\u094b\u0902\u0928\u0947 \u0907\u0938\u0947 \u0938\u092c\u0938\u0947 \u092a\u0939\u0932\u0947 \"N. Claus (de Siam)\" \u0915\u0947 \u0915\u093c\u0932\u092e\u0940 \u0928\u093e\u092e \u0938\u0947 \u092c\u0947\u091a\u093e \u2014 \u091c\u094b \u0909\u0928\u0915\u0947 \u0917\u0943\u0939\u0928\u0917\u0930 \u0915\u0947 \u0928\u093e\u092e \"Lucas d'Amiens\" \u0915\u093e \u090f\u0915 \u0905\u0928\u093e\u0917\u094d\u0930\u093e\u092e \u0939\u0948\u0964",methods:"\u092a\u0941\u0928\u0930\u093e\u0935\u0930\u094d\u0924\u0940 (recursive) \u0922\u0902\u0917 \u0938\u0947 \u0938\u094b\u091a\u093f\u090f: N \u091a\u0915\u0924\u093f\u092f\u094b\u0902 \u0915\u0947 \u0922\u0947\u0930 \u0915\u094b \u0939\u093f\u0932\u093e\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f, \u092a\u0939\u0932\u0947 \u090a\u092a\u0930 \u0915\u0940 N-1 \u091a\u0915\u0924\u093f\u092f\u094b\u0902 \u0915\u094b \u092c\u091a\u0940 \u0939\u0941\u0908 \u0916\u0942\u0901\u091f\u0940 \u092a\u0930 \u0932\u0947 \u091c\u093e\u0907\u090f, \u0938\u092c\u0938\u0947 \u092c\u0921\u093c\u0940 \u091a\u0915\u0924\u0940 \u0915\u094b \u0906\u0930-\u092a\u093e\u0930 \u0938\u0930\u0915\u093e\u0907\u090f, \u092b\u093f\u0930 N-1 \u0915\u094b \u0935\u093e\u092a\u0938 \u0909\u0938\u0915\u0947 \u090a\u092a\u0930 \u0930\u0916 \u0926\u0940\u091c\u093f\u090f\u0964 \u0938\u092c\u0938\u0947 \u092a\u093e\u0938 \u0935\u093e\u0932\u0940 \u0935\u0948\u0927 \u091a\u093e\u0932 \u091d\u092a\u091f\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u0915\u0941\u091b \u091a\u093e\u0932\u0947\u0902 \u0906\u0917\u0947 \u0915\u0940 \u092f\u094b\u091c\u0928\u093e \u092c\u0928\u093e\u0907\u090f, \u0914\u0930 \u091a\u0915\u0924\u093f\u092f\u094b\u0902 \u0915\u0940 \u0935\u093f\u0937\u092e \u0938\u0902\u0916\u094d\u092f\u093e \u0915\u0947 \u0932\u093f\u090f \u0938\u092c\u0938\u0947 \u091b\u094b\u091f\u0940 \u091a\u0915\u0924\u0940 \u0915\u094b \u0932\u0915\u094d\u0937\u094d\u092f-\u0916\u0942\u0901\u091f\u0940 \u0915\u0940 \u0913\u0930 \u092d\u0947\u091c\u0915\u0930 \u0936\u0941\u0930\u0941\u0906\u0924 \u0915\u0940\u091c\u093f\u090f, \u0939\u0930 \u092c\u093e\u0930\u0940 \u0909\u0938\u0915\u0940 \u0926\u093f\u0936\u093e \u092c\u0926\u0932\u0924\u0947 \u0939\u0941\u090f\u0964",duration:"\u091b\u094b\u091f\u0947, \u090f\u0915\u093e\u0917\u094d\u0930 \u0938\u0924\u094d\u0930 \u2014 10 \u0938\u0947 15 \u092e\u093f\u0928\u091f \u0915\u0947 \u2014 \u0938\u092c\u0938\u0947 \u0905\u091a\u094d\u091b\u0947 \u0930\u0939\u0924\u0947 \u0939\u0948\u0902, \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u0915\u0941\u091b \u092c\u093e\u0930\u0964 \u091c\u092c \u0906\u092a \u0915\u093f\u0938\u0940 \u0926\u0940 \u0939\u0941\u0908 \u090a\u0901\u091a\u093e\u0908 \u0915\u094b \u0938\u092c\u0938\u0947 \u0915\u092e \u091a\u093e\u0932\u094b\u0902 \u092e\u0947\u0902 \u0939\u0932 \u0915\u0930 \u092a\u093e\u0928\u0947 \u0932\u0917\u0947\u0902, \u0924\u094b \u0909\u0938\u0940 \u0906\u0938\u093e\u0928 \u0906\u0915\u093e\u0930 \u0915\u094b \u0926\u094b\u0939\u0930\u093e\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u090f\u0915 \u091a\u0915\u0924\u0940 \u0914\u0930 \u091c\u094b\u0921\u093c \u0926\u0940\u091c\u093f\u090f\u0964",research:"\u0938\u092c\u0938\u0947 \u092a\u0941\u0916\u093c\u094d\u0924\u093e \u0938\u092c\u0942\u0924 \u0920\u0940\u0915 \u0909\u0938\u0940 \u092c\u093e\u0924 \u0915\u0947 \u0932\u093f\u090f \u0939\u0948 \u091c\u093f\u0938\u0915\u0940 \u0906\u092a \u0909\u092e\u094d\u092e\u0940\u0926 \u0915\u0930\u0947\u0902\u0917\u0947: \u0906\u092a \u0916\u093c\u0941\u0926 \u0907\u0938 \u092a\u0939\u0947\u0932\u0940 \u092e\u0947\u0902 \u0914\u0930 \u0907\u0938\u0938\u0947 \u0915\u093c\u0930\u0940\u092c\u0940 \u0930\u0942\u092a \u0938\u0947 \u091c\u0941\u0921\u093c\u0947 \u092f\u094b\u091c\u0928\u093e-\u0915\u093e\u0930\u094d\u092f\u094b\u0902 \u092e\u0947\u0902 \u0924\u0947\u091c\u093c \u0914\u0930 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0938\u091f\u0940\u0915 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u092f\u0939 \u092f\u094b\u091c\u0928\u093e-\u0915\u094d\u0937\u092e\u0924\u093e \u0915\u0940 \u090f\u0915 \u0938\u092e\u094d\u092e\u093e\u0928\u093f\u0924 \u0915\u094d\u0932\u0940\u0928\u093f\u0915\u0932 \u092e\u093e\u092a \u092c\u0928\u0940 \u0939\u0941\u0908 \u0939\u0948\u0964 \u092f\u0947 \u092c\u0921\u093c\u0947 \u0926\u093e\u0935\u0947 \u0915\u093f \u092f\u0939 \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u092c\u0941\u0926\u094d\u0927\u093f \u092f\u093e \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0940 \u0938\u092e\u0938\u094d\u092f\u093e-\u0938\u092e\u093e\u0927\u093e\u0928 \u0915\u094d\u0937\u092e\u0924\u093e \u0915\u094b \u092c\u0922\u093c\u093e\u0924\u093e \u0939\u0948, \u0915\u0939\u0940\u0902 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0915\u092e\u091c\u093c\u094b\u0930 \u0939\u0948\u0902 \u2014 \u0926\u093f\u092e\u093e\u0917\u0940-\u0915\u0938\u0930\u0924 \u0915\u0940 \u0938\u092e\u0940\u0915\u094d\u0937\u093e\u090f\u0901 \u092c\u093e\u0930-\u092c\u093e\u0930 \u092a\u093e\u0924\u0940 \u0939\u0948\u0902 \u0915\u093f \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0926\u0942\u0930\u0917\u093e\u092e\u0940 \u091f\u094d\u0930\u093e\u0902\u0938\u092b\u093c\u0930 \u092c\u0939\u0941\u0924 \u0915\u092e \u0939\u094b\u0924\u093e \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u092c\u0921\u093c\u0947-\u092c\u0921\u093c\u0947 \u0935\u093e\u0926\u094b\u0902 \u0915\u094b \u0938\u093e\u0935\u0927\u093e\u0928\u0940 \u0938\u0947 \u0932\u0940\u091c\u093f\u090f\u0964",rec:"\u0939\u0930 \u092c\u093e\u0930 \u0939\u0932 \u0915\u0930\u0928\u0947 \u0915\u0947 \u092c\u093e\u0926 \u0909\u0938\u0947 \u0905\u092a\u0928\u0947 \u092e\u0928 \u092e\u0947\u0902 \u0926\u094b\u092c\u093e\u0930\u093e \u091a\u0932\u093e\u0907\u090f \u0914\u0930 \u0916\u093c\u0941\u0926 \u0938\u0947 \u092a\u0942\u091b\u093f\u090f \u0915\u093f \u0915\u094d\u092f\u093e \u0915\u094b\u0908 \u091b\u094b\u091f\u093e \u0930\u093e\u0938\u094d\u0924\u093e \u092e\u094c\u091c\u0942\u0926 \u0925\u093e \u2014 \u0905\u092a\u0928\u0940 \u0939\u0940 \u091a\u093e\u0932\u094b\u0902 \u092a\u0930 \u0938\u094b\u091a-\u0935\u093f\u091a\u093e\u0930 \u0915\u0930\u0928\u093e \u0905\u0902\u0927\u0947 \u0926\u094b\u0939\u0930\u093e\u0935 \u0915\u0940 \u0924\u0941\u0932\u0928\u093e \u092e\u0947\u0902 \u092f\u094b\u091c\u0928\u093e-\u0915\u094d\u0937\u092e\u0924\u093e \u0915\u094b \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0938\u0927\u093e\u0924\u093e \u0939\u0948\u0964",faq:[["\u0915\u094d\u092f\u093e \u0939\u092e\u0947\u0936\u093e \u090f\u0915 \u0938\u092c\u0938\u0947 \u0905\u091a\u094d\u091b\u093e \u0939\u0932 \u0939\u094b\u0924\u093e \u0939\u0948?","\u0939\u093e\u0901\u0964 \u091a\u0915\u0924\u093f\u092f\u094b\u0902 \u0915\u0940 \u0915\u093f\u0938\u0940 \u092d\u0940 \u0938\u0902\u0916\u094d\u092f\u093e \u0915\u0947 \u0932\u093f\u090f \u090f\u0915 \u0939\u0940 \u0938\u092c\u0938\u0947 \u091b\u094b\u091f\u093e \u0939\u0932 \u0939\u094b\u0924\u093e \u0939\u0948, \u0914\u0930 \u0909\u0938\u092e\u0947\u0902 2 \u0915\u0940 N \u0918\u093e\u0924 \u0918\u091f\u093e\u0935 1 \u091a\u093e\u0932\u0947\u0902 \u0932\u0917\u0924\u0940 \u0939\u0948\u0902 \u2014 3 \u091a\u0915\u0924\u093f\u092f\u094b\u0902 \u0915\u0947 \u0932\u093f\u090f 7 \u091a\u093e\u0932\u0947\u0902, 10 \u0915\u0947 \u0932\u093f\u090f 1023\u0964"],["\u0915\u094d\u092f\u093e \u0907\u0938\u0938\u0947 \u092e\u0948\u0902 \u0915\u0941\u0932 \u092e\u093f\u0932\u093e\u0915\u0930 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0939\u094b\u0936\u093f\u092f\u093e\u0930 \u092c\u0928 \u091c\u093e\u090a\u0901\u0917\u093e?","\u0908\u092e\u093e\u0928\u0926\u093e\u0930\u0940 \u0938\u0947 \u0915\u0939\u0947\u0902 \u0924\u094b, \u0935\u094d\u092f\u093e\u092a\u0915 \u0905\u0930\u094d\u0925 \u092e\u0947\u0902 \u0936\u093e\u092f\u0926 \u0928\u0939\u0940\u0902\u0964 \u0906\u092a \u0907\u0938 \u092a\u0939\u0947\u0932\u0940 \u092e\u0947\u0902 \u0914\u0930 \u0907\u0938\u0938\u0947 \u092e\u093f\u0932\u0924\u0940-\u091c\u0941\u0932\u0924\u0940 \u092f\u094b\u091c\u0928\u093e-\u0915\u093e\u0930\u094d\u092f\u094b\u0902 \u092e\u0947\u0902 \u0938\u093e\u092b\u093c \u0924\u094c\u0930 \u092a\u0930 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u090f\u0901\u0917\u0947, \u092a\u0930 \u0907\u0938\u0915\u0947 \u0938\u092c\u0942\u0924 \u0915\u092e\u091c\u093c\u094b\u0930 \u0939\u0948\u0902 \u0915\u093f \u092f\u0939 \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u092c\u0941\u0926\u094d\u0927\u093f \u092f\u093e \u0905\u0938\u0902\u092c\u0902\u0927\u093f\u0924 \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0947 \u0915\u094c\u0936\u0932\u094b\u0902 \u0915\u094b \u092c\u0922\u093c\u093e\u0924\u093e \u0939\u0948\u0964"],["\u092e\u0948\u0902 \u0905\u0902\u0924 \u0915\u0947 \u092a\u093e\u0938 \u092c\u093e\u0930-\u092c\u093e\u0930 \u0915\u094d\u092f\u094b\u0902 \u0905\u091f\u0915 \u091c\u093e\u0924\u093e \u0939\u0942\u0901?","\u0906\u092e\u0924\u094c\u0930 \u092a\u0930 \u0907\u0938\u0932\u093f\u090f \u0915\u093f \u0906\u092a\u0928\u0947 \u092c\u093f\u0928\u093e \u092f\u094b\u091c\u0928\u093e \u0915\u0947 \u091a\u093e\u0932 \u091a\u0932\u0940\u0964 \u0932\u0915\u094d\u0937\u094d\u092f \u0938\u0947 \u0909\u0932\u094d\u091f\u093e \u0915\u093e\u092e \u0915\u0930\u0928\u0947 \u0915\u0940 \u0915\u094b\u0936\u093f\u0936 \u0915\u0940\u091c\u093f\u090f \u0914\u0930 \u0905\u0915\u0947\u0932\u0940 \u091a\u0915\u0924\u093f\u092f\u094b\u0902 \u0915\u0947 \u092c\u091c\u093e\u092f \u092a\u0942\u0930\u0947 \u0909\u092a-\u0922\u0947\u0930\u094b\u0902 \u0915\u094b \u0939\u093f\u0932\u093e\u0928\u0947 \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u0938\u094b\u091a\u093f\u090f \u2014 \u092f\u0939\u0940 \u0935\u0939 \u092a\u0941\u0928\u0930\u093e\u0935\u0930\u094d\u0924\u0940 \u0924\u0930\u0915\u0940\u092c \u0939\u0948 \u091c\u093f\u0938\u0938\u0947 \u092c\u093e\u0924 \u091c\u092e \u091c\u093e\u0924\u0940 \u0939\u0948\u0964"]],variants:"\u0906\u092e \u092c\u0926\u0932\u093e\u0935 \u091a\u0915\u0924\u093f\u092f\u094b\u0902 \u0915\u0940 \u0938\u0902\u0916\u094d\u092f\u093e \u092c\u0926\u0932\u0924\u0947 \u0939\u0948\u0902 (\u091a\u093e\u0932\u094b\u0902 \u0915\u0940 \u0928\u094d\u092f\u0942\u0928\u0924\u092e \u0938\u0902\u0916\u094d\u092f\u093e \u0939\u092e\u0947\u0936\u093e 2 \u0915\u0940 N \u0918\u093e\u0924, \u0918\u091f\u093e\u0935 1 \u0939\u094b\u0924\u0940 \u0939\u0948), \u090f\u0915 \u091a\u094c\u0925\u0940 \u0916\u0942\u0901\u091f\u0940 \u091c\u094b\u0921\u093c\u0924\u0947 \u0939\u0948\u0902 (the Reve's puzzle), \u092f\u093e \u0905\u0924\u093f\u0930\u093f\u0915\u094d\u0924 \u0928\u093f\u092f\u092e \u0925\u094b\u092a\u0924\u0947 \u0939\u0948\u0902 \u091c\u0948\u0938\u0947 \u091a\u0915\u0924\u093f\u092f\u094b\u0902 \u0915\u094b \u0938\u093f\u0930\u094d\u092b\u093c \u092c\u0917\u0932 \u0935\u093e\u0932\u0940 \u0916\u0942\u0901\u091f\u093f\u092f\u094b\u0902 \u0915\u0947 \u092c\u0940\u091a \u0939\u0940 \u0939\u093f\u0932\u093e\u0928\u093e\u0964 \u0938\u0902\u092c\u0902\u0927\u093f\u0924 \u092f\u094b\u091c\u0928\u093e-\u092a\u0939\u0947\u0932\u093f\u092f\u094b\u0902 \u092e\u0947\u0902 Tower of London \u0936\u093e\u092e\u093f\u0932 \u0939\u0948, \u091c\u094b \u0938\u0902\u091c\u094d\u091e\u093e\u0928\u093e\u0924\u094d\u092e\u0915 \u092a\u0930\u0940\u0915\u094d\u0937\u0923 \u092e\u0947\u0902 \u0935\u094d\u092f\u093e\u092a\u0915 \u0930\u0942\u092a \u0938\u0947 \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0939\u094b\u0924\u0940 \u0939\u0948\u0964"},zh:{about:"\u6c49\u8bfa\u5854\u662f\u4e00\u4e2a\u8c1c\u9898\uff0c\u6709\u4e09\u6839\u67f1\u5b50\u548c\u4e00\u645e\u5927\u5c0f\u4e0d\u4e00\u7684\u5706\u76d8\u3002\u4f60\u8981\u628a\u6574\u645e\u5706\u76d8\u4ece\u7b2c\u4e00\u6839\u67f1\u5b50\u79fb\u5230\u6700\u540e\u4e00\u6839\uff0c\u6bcf\u6b21\u53ea\u80fd\u79fb\u4e00\u4e2a\u5706\u76d8\uff0c\u4e14\u4efb\u4f55\u65f6\u5019\u90fd\u4e0d\u80fd\u628a\u5927\u76d8\u538b\u5728\u5c0f\u76d8\u4e0a\u9762\u3002",benefit:"\u5b83\u8bad\u7ec3\u63d0\u524d\u89c4\u5212\u548c\u76ee\u6807\u5bfc\u5411\u601d\u7ef4\uff1a\u4f60\u5f97\u628a\u7ec8\u5c40\u72b6\u6001\u8bb0\u5728\u5fc3\u91cc\uff0c\u518d\u63a8\u6f14\u51fa\u4e00\u8fde\u4e32\u5b50\u6b65\u9aa4\u6765\u8fbe\u6210\u5b83\u3002\u5fc3\u7406\u5b66\u5bb6\u628a\u5b83\u5f53\u4f5c\u8861\u91cf\u6267\u884c\u529f\u80fd\u548c\u989d\u53f6\u89c4\u5212\u80fd\u529b\u7684\u7ecf\u5178\u6307\u6807\u3002",history:"Lucas\u4e8e1883\u5e74\u5c06\u5b83\u4f5c\u4e3a\u5546\u54c1\u51fa\u552e\uff0c\u5e76\u88f9\u4e0a\u4e00\u5219\u675c\u64b0\u7684\u4f20\u8bf4\uff1a\u67d0\u5ea7\u5bfa\u5e99\u91cc\u7684\u50e7\u4fa3\u5728\u79fb\u52a864\u4e2a\u91d1\u76d8\uff0c\u7b49\u4ed6\u4eec\u79fb\u5b8c\uff0c\u4e16\u754c\u636e\u8bf4\u5c31\u4f1a\u7ec8\u7ed3\u3002\u8fd9\u4e2a\u8c1c\u9898\u4f5c\u4e3a\u4e00\u79cd\u5ba2\u5385\u6e38\u620f\u8fc5\u901f\u6d41\u4f20\uff0c\u540e\u6765\u53c8\u6210\u4e3a\u6570\u5b66\u3001\u8ba1\u7b97\u673a\u79d1\u5b66\u548c\u795e\u7ecf\u5fc3\u7406\u5b66\u4e2d\u7684\u6807\u51c6\u5de5\u5177\u3002",creator:"\u5b83\u7531\u6cd5\u56fd\u6570\u5b66\u5bb6\xc9douard Lucas\u4e8e1883\u5e74\u53d1\u660e\uff0c\u4ed6\u6700\u521d\u4ee5\u7b14\u540d\u300cN. Claus (de Siam)\u300d\u51fa\u552e\u5b83\u2014\u2014\u8fd9\u662f\u4ed6\u5bb6\u4e61\u540d\u5b57\u300cLucas d'Amiens\u300d\u7684\u53d8\u4f4d\u8bcd\u3002",methods:"\u7528\u9012\u5f52\u6765\u601d\u8003\uff1a\u8981\u79fb\u52a8N\u4e2a\u5706\u76d8\u7684\u4e00\u645e\uff0c\u5148\u628a\u9876\u4e0a\u7684N-1\u4e2a\u79fb\u5230\u5907\u7528\u67f1\uff0c\u518d\u628a\u6700\u5927\u7684\u90a3\u4e2a\u632a\u8fc7\u53bb\uff0c\u7136\u540e\u628a\u90a3N-1\u4e2a\u79fb\u56de\u5b83\u4e0a\u9762\u3002\u8981\u63d0\u524d\u60f3\u597d\u51e0\u6b65\uff0c\u800c\u4e0d\u662f\u968f\u624b\u6293\u6700\u8fd1\u7684\u4e00\u4e2a\u5408\u6cd5\u79fb\u52a8\uff1b\u5f53\u5706\u76d8\u6570\u4e3a\u5947\u6570\u65f6\uff0c\u5f00\u5c40\u5148\u628a\u6700\u5c0f\u7684\u5706\u76d8\u671d\u76ee\u6807\u67f1\u79fb\u52a8\uff0c\u5e76\u8ba9\u5b83\u6bcf\u56de\u5408\u4ea4\u66ff\u6539\u53d8\u65b9\u5411\u3002",duration:"10\u523015\u5206\u949f\u3001\u77ed\u800c\u4e13\u6ce8\u7684\u7ec3\u4e60\u6548\u679c\u6700\u597d\uff0c\u4e00\u5468\u51e0\u6b21\u3002\u4e00\u65e6\u4f60\u80fd\u4ee5\u6700\u4f18\u89e3\u6cd5\u89e3\u51fa\u67d0\u4e2a\u9ad8\u5ea6\uff0c\u5c31\u52a0\u4e00\u4e2a\u5706\u76d8\uff0c\u800c\u4e0d\u662f\u53cd\u590d\u53bb\u505a\u540c\u4e00\u4e2a\u7b80\u5355\u7684\u5c3a\u5bf8\u3002",research:"\u8bc1\u636e\u6700\u6709\u529b\u7684\u6070\u6070\u662f\u4f60\u80fd\u60f3\u5230\u7684\u90a3\u90e8\u5206\uff1a\u4f60\u4f1a\u5728\u8fd9\u4e2a\u8c1c\u9898\u672c\u8eab\u4ee5\u53ca\u4e0e\u4e4b\u5bc6\u5207\u76f8\u5173\u7684\u89c4\u5212\u4efb\u52a1\u4e0a\u53d8\u5f97\u66f4\u5feb\u3001\u66f4\u51c6\u786e\uff0c\u800c\u4e14\u5b83\u81f3\u4eca\u4ecd\u662f\u4e00\u9879\u53d7\u8ba4\u53ef\u7684\u89c4\u5212\u80fd\u529b\u4e34\u5e8a\u6307\u6807\u3002\u81f3\u4e8e\u5b83\u80fd\u63d0\u5347\u4e00\u822c\u667a\u529b\u6216\u65e5\u5e38\u95ee\u9898\u89e3\u51b3\u80fd\u529b\u4e4b\u7c7b\u7684\u5bbd\u6cdb\u8bf4\u6cd5\uff0c\u4f9d\u636e\u5219\u5f31\u5f97\u591a\u2014\u2014\u8111\u8bad\u7ec3\u7684\u7efc\u8ff0\u5c61\u6b21\u53d1\u73b0\u53ef\u9760\u7684\u8fdc\u8fc1\u79fb\u5f88\u5c11\uff0c\u6240\u4ee5\u5bf9\u90a3\u4e9b\u5b8f\u5927\u627f\u8bfa\u8981\u4fdd\u6301\u8c28\u614e\u3002",rec:"\u6bcf\u89e3\u5b8c\u4e00\u6b21\uff0c\u5c31\u5728\u8111\u4e2d\u91cd\u653e\u4e00\u904d\uff0c\u95ee\u95ee\u81ea\u5df1\u662f\u5426\u5b58\u5728\u66f4\u77ed\u7684\u8def\u5f84\u2014\u2014\u5bf9\u81ea\u5df1\u8d70\u6cd5\u7684\u53cd\u601d\uff0c\u6bd4\u76f2\u76ee\u91cd\u590d\u66f4\u80fd\u8bad\u7ec3\u89c4\u5212\u80fd\u529b\u3002",faq:[["\u662f\u5426\u603b\u5b58\u5728\u4e00\u4e2a\u6700\u4f18\u89e3\uff1f","\u662f\u7684\u3002\u5bf9\u4efb\u610f\u6570\u91cf\u7684\u5706\u76d8\uff0c\u90fd\u5b58\u5728\u552f\u4e00\u7684\u6700\u77ed\u89e3\uff0c\u6240\u9700\u79fb\u52a8\u6b21\u6570\u4e3a2\u7684N\u6b21\u65b9\u51cf1\u2014\u20143\u4e2a\u5706\u76d8\u89817\u6b65\uff0c10\u4e2a\u89811023\u6b65\u3002"],["\u5b83\u4f1a\u8ba9\u6211\u6574\u4f53\u53d8\u806a\u660e\u5417\uff1f","\u8001\u5b9e\u8bf4\uff0c\u5728\u5e7f\u4e49\u4e0a\u5927\u6982\u4e0d\u4f1a\u3002\u4f60\u4f1a\u5728\u8fd9\u4e2a\u8c1c\u9898\u548c\u7c7b\u4f3c\u7684\u89c4\u5212\u4efb\u52a1\u4e0a\u660e\u663e\u53d8\u597d\uff0c\u4f46\u300c\u5b83\u80fd\u63d0\u5347\u4e00\u822c\u667a\u529b\u6216\u65e0\u5173\u65e5\u5e38\u6280\u80fd\u300d\u7684\u8bc1\u636e\u5f88\u5f31\u3002"],["\u4e3a\u4ec0\u4e48\u6211\u8001\u662f\u5728\u5feb\u7ed3\u675f\u65f6\u5361\u4f4f\uff1f","\u901a\u5e38\u662f\u56e0\u4e3a\u4f60\u6ca1\u8ba1\u5212\u5c31\u52a8\u4e86\u624b\u3002\u8bd5\u7740\u4ece\u76ee\u6807\u5012\u63a8\uff0c\u5e76\u4ee5\u300c\u79fb\u52a8\u6574\u645e\u5b50\u5854\u300d\u800c\u975e\u300c\u5355\u4e2a\u5706\u76d8\u300d\u7684\u65b9\u5f0f\u6765\u601d\u8003\u2014\u2014\u8fd9\u6b63\u662f\u8ba9\u4e00\u5207\u8c41\u7136\u5f00\u6717\u7684\u9012\u5f52\u8bc0\u7a8d\u3002"]],variants:"\u5e38\u89c1\u53d8\u5316\u4f1a\u6539\u53d8\u5706\u76d8\u6570\u91cf\uff08\u6700\u5c11\u79fb\u52a8\u6b21\u6570\u6c38\u8fdc\u662f2\u7684N\u6b21\u65b9\u51cf1\uff09\u3001\u52a0\u4e0a\u7b2c\u56db\u6839\u67f1\u5b50\uff08\u5373Reve's puzzle\uff09\uff0c\u6216\u65bd\u52a0\u989d\u5916\u89c4\u5219\uff0c\u6bd4\u5982\u53ea\u5141\u8bb8\u5728\u76f8\u90bb\u67f1\u5b50\u4e4b\u95f4\u79fb\u52a8\u5706\u76d8\u3002\u76f8\u5173\u7684\u89c4\u5212\u8c1c\u9898\u5305\u62ec\u4f26\u6566\u5854\uff08Tower of London\uff09\uff0c\u5b83\u88ab\u5e7f\u6cdb\u7528\u4e8e\u8ba4\u77e5\u6d4b\u9a8c\u3002"}},inhibition:{ru:{about:"\xab\u0422\u043e\u0440\u043c\u043e\u0436\u0435\u043d\u0438\u0435\xbb \u2014 \u044d\u0442\u043e \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u0435 \u043f\u043e \u0441\u0445\u0435\u043c\u0435 go/no-go (\u0440\u0435\u0430\u0433\u0438\u0440\u0443\u0439 / \u043d\u0435 \u0440\u0435\u0430\u0433\u0438\u0440\u0443\u0439). \u0421\u0438\u0433\u043d\u0430\u043b\u044b \u0432\u0441\u043f\u044b\u0445\u0438\u0432\u0430\u044e\u0442 \u043f\u043e \u043e\u0434\u043d\u043e\u043c\u0443, \u0438 \u043d\u0430 \u0441\u0438\u0433\u043d\u0430\u043b \xab\u0440\u0435\u0430\u0433\u0438\u0440\u0443\u0439\xbb \u043d\u0443\u0436\u043d\u043e \u0431\u044b\u0441\u0442\u0440\u043e \u043e\u0442\u0432\u0435\u0442\u0438\u0442\u044c \u043d\u0430\u0436\u0430\u0442\u0438\u0435\u043c, \u0430 \u043d\u0430 \u0441\u0438\u0433\u043d\u0430\u043b \xab\u043d\u0435 \u0440\u0435\u0430\u0433\u0438\u0440\u0443\u0439\xbb \u2014 \u043f\u043e\u043b\u043d\u043e\u0441\u0442\u044c\u044e \u0443\u0434\u0435\u0440\u0436\u0430\u0442\u044c \u0440\u0443\u043a\u0443. \u0421\u0438\u0433\u043d\u0430\u043b\u043e\u0432 \xab\u0440\u0435\u0430\u0433\u0438\u0440\u0443\u0439\xbb \u0431\u043e\u043b\u044c\u0448\u0438\u043d\u0441\u0442\u0432\u043e, \u0442\u0430\u043a \u0447\u0442\u043e \u043d\u0430\u0436\u0430\u0442\u0438\u0435 \u043f\u0440\u0435\u0432\u0440\u0430\u0449\u0430\u0435\u0442\u0441\u044f \u0432 \u0440\u0435\u0444\u043b\u0435\u043a\u0441, \u0438 \u0432\u0441\u044f \u0441\u043b\u043e\u0436\u043d\u043e\u0441\u0442\u044c \u0432 \u0442\u043e\u043c, \u0447\u0442\u043e\u0431\u044b \u0443\u0441\u043f\u0435\u0442\u044c \u0441\u0435\u0431\u044f \u043e\u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u044c \u043f\u0435\u0440\u0435\u0434 \u0440\u0435\u0434\u043a\u0438\u043c \xab\u043d\u0435 \u0440\u0435\u0430\u0433\u0438\u0440\u0443\u0439\xbb.",benefit:"\u0423\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u0435 \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u0442\u043e\u0440\u043c\u043e\u0437\u043d\u044b\u0439 \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044c \u2014 \u0442\u0443 \u0447\u0430\u0441\u0442\u044c \u0443\u043f\u0440\u0430\u0432\u043b\u044f\u044e\u0449\u0438\u0445 \u0444\u0443\u043d\u043a\u0446\u0438\u0439, \u0447\u0442\u043e \u043f\u043e\u0437\u0432\u043e\u043b\u044f\u0435\u0442 \u043e\u0431\u043e\u0440\u0432\u0430\u0442\u044c \u0443\u0436\u0435 \u0437\u0430\u043f\u0443\u0449\u0435\u043d\u043d\u043e\u0435 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435. \u0417\u0430\u043e\u0434\u043d\u043e \u043d\u0430\u0433\u0440\u0443\u0436\u0430\u0435\u0442 \u0443\u0441\u0442\u043e\u0439\u0447\u0438\u0432\u043e\u0435 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435: \u0441\u0442\u043e\u0438\u0442 \u043e\u0442\u0432\u043b\u0435\u0447\u044c\u0441\u044f \u043d\u0430 \u043c\u0438\u0433, \u0438 \u043f\u0430\u043b\u0435\u0446 \u043d\u0430\u0436\u0438\u043c\u0430\u0435\u0442 \u0441\u0430\u043c.",history:"\u0421\u0445\u0435\u043c\u0430 go/no-go \u0432\u044b\u0440\u043e\u0441\u043b\u0430 \u0438\u0437 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u0439 \u0432\u0440\u0435\u043c\u0435\u043d\u0438 \u0440\u0435\u0430\u043a\u0446\u0438\u0438 \u0434\u0435\u0432\u044f\u0442\u043d\u0430\u0434\u0446\u0430\u0442\u043e\u0433\u043e \u0432\u0435\u043a\u0430 \u0438 \u0432 \u0434\u0432\u0430\u0434\u0446\u0430\u0442\u043e\u043c \u0441\u0442\u0430\u043b\u0430 \u0440\u0430\u0431\u043e\u0447\u0438\u043c \u0438\u043d\u0441\u0442\u0440\u0443\u043c\u0435\u043d\u0442\u043e\u043c \u043a\u043b\u0438\u043d\u0438\u0447\u0435\u0441\u043a\u043e\u0439 \u043d\u0435\u0439\u0440\u043e\u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u0438, \u0433\u0434\u0435 \u043d\u0435\u0441\u043f\u043e\u0441\u043e\u0431\u043d\u043e\u0441\u0442\u044c \u0441\u0434\u0435\u0440\u0436\u0430\u0442\u044c \u043e\u0442\u0432\u0435\u0442 \u0441\u0432\u044f\u0437\u044b\u0432\u0430\u043b\u0438 \u0441 \u0440\u0430\u0431\u043e\u0442\u043e\u0439 \u043b\u043e\u0431\u043d\u044b\u0445 \u0434\u043e\u043b\u0435\u0439. \u041e\u0442\u0442\u0443\u0434\u0430 \u043e\u043d\u0430 \u043f\u0435\u0440\u0435\u0448\u043b\u0430 \u0432 \u043a\u043e\u0433\u043d\u0438\u0442\u0438\u0432\u043d\u0443\u044e \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u044e \u0438 \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u044e \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u044f, \u0430 \u0432 \u043f\u043e\u0441\u043b\u0435\u0434\u043d\u0438\u0435 \u0433\u043e\u0434\u044b \u2014 \u0432 \u043c\u043e\u0431\u0438\u043b\u044c\u043d\u044b\u0435 \u0442\u0440\u0435\u043d\u0430\u0436\u0451\u0440\u044b \u0438 \u0440\u0430\u0431\u043e\u0442\u044b \u043f\u043e \u0438\u0437\u043c\u0435\u043d\u0435\u043d\u0438\u044e \u043f\u0438\u0449\u0435\u0432\u044b\u0445 \u0438 \u0430\u043b\u043a\u043e\u0433\u043e\u043b\u044c\u043d\u044b\u0445 \u043f\u0440\u0438\u0432\u044b\u0447\u0435\u043a.",creator:"\u0415\u0434\u0438\u043d\u043e\u0433\u043e \u0430\u0432\u0442\u043e\u0440\u0430 \u043d\u0435\u0442. \u041c\u0435\u0442\u043e\u0434 go/no-go \u0432\u043e\u0441\u0445\u043e\u0434\u0438\u0442 \u043a \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u0438 \u0438\u0437\u043c\u0435\u0440\u0435\u043d\u0438\u044f \u0432\u0440\u0435\u043c\u0435\u043d\u0438 \u0440\u0435\u0430\u043a\u0446\u0438\u0438, \u043d\u0430\u0447\u0430\u043b\u043e \u043a\u043e\u0442\u043e\u0440\u043e\u0439 \u043e\u0431\u044b\u0447\u043d\u043e \u0441\u0432\u044f\u0437\u044b\u0432\u0430\u044e\u0442 \u0441 \u0424\u0440\u0430\u043d\u0446\u0438\u0441\u043a\u043e\u043c \u0414\u043e\u043d\u0434\u0435\u0440\u0441\u043e\u043c (1868), \u0430 \u0435\u0433\u043e \u043d\u044b\u043d\u0435\u0448\u043d\u0438\u0439 \u0432\u0438\u0434 \u0441\u043b\u043e\u0436\u0438\u043b\u0441\u044f \u0437\u0430 \u0434\u0432\u0430\u0434\u0446\u0430\u0442\u044b\u0439 \u0432\u0435\u043a \u0443\u0441\u0438\u043b\u0438\u044f\u043c\u0438 \u043d\u0435\u0439\u0440\u043e\u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u043e\u0432, \u0438\u0437\u0443\u0447\u0430\u0432\u0448\u0438\u0445 \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044c \u0438\u043c\u043f\u0443\u043b\u044c\u0441\u043e\u0432 \u0438 \u043b\u043e\u0431\u043d\u044b\u0435 \u0434\u043e\u043b\u0438, \u0430 \u043d\u0435 \u043e\u0434\u043d\u043e\u0433\u043e \u043a\u043e\u043d\u043a\u0440\u0435\u0442\u043d\u043e\u0433\u043e \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u044f.",methods:"\u0414\u0435\u0440\u0436\u0438\u0442\u0435 \u043f\u0430\u043b\u0435\u0446 \u0440\u0430\u0441\u0441\u043b\u0430\u0431\u043b\u0435\u043d\u043d\u044b\u043c \u0438 \u0433\u043e\u0442\u043e\u0432\u044b\u043c, \u0430 \u043d\u0435 \u043d\u0430\u043f\u0440\u044f\u0436\u0451\u043d\u043d\u043e \u0437\u0430\u043d\u0435\u0441\u0451\u043d\u043d\u044b\u043c \u0434\u043b\u044f \u0443\u0434\u0430\u0440\u0430: \u0432\u0441\u044f \u0441\u0443\u0442\u044c \u0432 \u0442\u043e\u043c, \u0447\u0442\u043e\u0431\u044b \u0443\u0441\u043f\u0435\u0442\u044c \u043e\u0442\u043c\u0435\u043d\u0438\u0442\u044c \u0434\u0432\u0438\u0436\u0435\u043d\u0438\u0435. \u041d\u0435 \u0433\u043e\u043d\u0438\u0442\u0435\u0441\u044c \u0437\u0430 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c\u044e \u043b\u044e\u0431\u043e\u0439 \u0446\u0435\u043d\u043e\u0439 \u2014 \u0437\u0434\u0435\u0441\u044c \u0432\u0430\u0436\u043d\u0430 \u043d\u0435 \u043b\u0438\u0448\u043d\u044f\u044f \u0434\u043e\u043b\u044f \u0441\u0435\u043a\u0443\u043d\u0434\u044b, \u0430 \u043e\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0435 \u043d\u0430\u0436\u0430\u0442\u0438\u0439 \u043d\u0430 \xab\u043d\u0435 \u0440\u0435\u0430\u0433\u0438\u0440\u0443\u0439\xbb. \u041f\u043e \u043c\u0435\u0440\u0435 \u043f\u0440\u043e\u0433\u0440\u0435\u0441\u0441\u0430 \u0443\u0441\u043a\u043e\u0440\u044f\u0439\u0442\u0435 \u0442\u0435\u043c\u043f \u0438\u043b\u0438 \u0443\u043c\u0435\u043d\u044c\u0448\u0430\u0439\u0442\u0435 \u0434\u043e\u043b\u044e \u0441\u0442\u043e\u043f-\u0441\u0438\u0433\u043d\u0430\u043b\u043e\u0432, \u0447\u0442\u043e\u0431\u044b \u0442\u043e\u0440\u043c\u043e\u0436\u0435\u043d\u0438\u0435 \u043e\u0441\u0442\u0430\u0432\u0430\u043b\u043e\u0441\u044c \u043f\u043e-\u043d\u0430\u0441\u0442\u043e\u044f\u0449\u0435\u043c\u0443 \u0442\u0440\u0443\u0434\u043d\u044b\u043c.",duration:"\u041a\u043e\u0440\u043e\u0442\u043a\u043e \u0438 \u0447\u0430\u0441\u0442\u043e \u043b\u0443\u0447\u0448\u0435, \u0447\u0435\u043c \u0434\u043e\u043b\u0433\u043e \u0438 \u0440\u0435\u0434\u043a\u043e. \u041f\u044f\u0442\u0438-\u0434\u0435\u0441\u044f\u0442\u0438 \u043c\u0438\u043d\u0443\u0442 \u0437\u0430 \u043f\u043e\u0434\u0445\u043e\u0434 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0440\u0430\u0437 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e \u0434\u043e\u0441\u0442\u0430\u0442\u043e\u0447\u043d\u043e, \u0430 \u043e\u0434\u0438\u043d \u0431\u043b\u043e\u043a \u0441\u0442\u043e\u0438\u0442 \u0434\u0435\u043b\u0430\u0442\u044c \u0442\u0430\u043a\u0438\u043c \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u043c, \u0447\u0442\u043e\u0431\u044b \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u043d\u0435 \u043f\u0440\u043e\u0441\u0435\u0434\u0430\u043b\u043e: \u0438\u043c\u0435\u043d\u043d\u043e \u0443\u0441\u0442\u0430\u043b\u043e\u0435 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u043f\u0440\u043e\u043f\u0443\u0441\u043a\u0430\u0435\u0442 \u0441\u0442\u043e\u043f-\u0441\u0438\u0433\u043d\u0430\u043b.",research:"\u041d\u0430\u0434\u0451\u0436\u043d\u043e \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043d\u043e \u043e\u0447\u0435\u0432\u0438\u0434\u043d\u043e\u0435: \u0441 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u043e\u0439 \u0432\u044b \u043b\u0443\u0447\u0448\u0435 \u0441\u043f\u0440\u0430\u0432\u043b\u044f\u0435\u0442\u0435\u0441\u044c \u0438\u043c\u0435\u043d\u043d\u043e \u0441 \u044d\u0442\u043e\u0439 \u0437\u0430\u0434\u0430\u0447\u0435\u0439 \u043d\u0430 \u0442\u043e\u0440\u043c\u043e\u0436\u0435\u043d\u0438\u0435 \u0438 \u0440\u0435\u0436\u0435 \u043d\u0430\u0436\u0438\u043c\u0430\u0435\u0442\u0435 \u043e\u0448\u0438\u0431\u043e\u0447\u043d\u043e. \u0417\u0430\u044f\u0432\u043b\u0435\u043d\u0438\u044f, \u0447\u0442\u043e \u044d\u0442\u043e \u0448\u0438\u0440\u043e\u043a\u043e \u043f\u043e\u0432\u044b\u0448\u0430\u0435\u0442 \u0441\u0430\u043c\u043e\u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044c \u0432 \u0431\u044b\u0442\u0443, \u0441\u043d\u0438\u0436\u0430\u0435\u0442 \u0438\u043c\u043f\u0443\u043b\u044c\u0441\u0438\u0432\u043d\u043e\u0441\u0442\u044c \u0432\u043e\u043e\u0431\u0449\u0435 \u0438\u043b\u0438 \u043e\u0431\u043e\u0441\u0442\u0440\u044f\u0435\u0442 \u043d\u0435\u0441\u0432\u044f\u0437\u0430\u043d\u043d\u043e\u0435 \u043c\u044b\u0448\u043b\u0435\u043d\u0438\u0435, \u0433\u043e\u0440\u0430\u0437\u0434\u043e \u0441\u043b\u0430\u0431\u0435\u0435. \u0418\u0437\u0432\u0435\u0441\u0442\u043d\u0430\u044f \u0440\u0430\u0431\u043e\u0442\u0430 \u042d\u043d\u0433\u0435 \u0441 \u043a\u043e\u043b\u043b\u0435\u0433\u0430\u043c\u0438 (2014) \u043d\u0435 \u043d\u0430\u0448\u043b\u0430 \u043d\u0430\u0441\u0442\u043e\u044f\u0449\u0435\u0433\u043e \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0430 \u0437\u0430 \u043f\u0440\u0435\u0434\u0435\u043b\u044b \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u043c\u044b\u0445 \u0437\u0430\u0434\u0430\u0447, \u0430 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u0435 2024 \u0433\u043e\u0434\u0430 \u043d\u0430 \u0434\u0435\u0442\u044f\u0445 \u043f\u043e\u043a\u0430\u0437\u0430\u043b\u043e, \u0447\u0442\u043e \u043f\u0440\u0438\u0446\u0435\u043b\u044c\u043d\u0430\u044f \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0430 \u0442\u043e\u0440\u043c\u043e\u0436\u0435\u043d\u0438\u044f \u043f\u043e\u0447\u0442\u0438 \u043d\u0435 \u043c\u0435\u043d\u044f\u0435\u0442 \u043d\u0438 \u043c\u043e\u0437\u0433, \u043d\u0438 \u043f\u043e\u0432\u0435\u0434\u0435\u043d\u0438\u0435. \u041f\u0438\u0449\u0435\u0432\u044b\u0435 \u0432\u0435\u0440\u0441\u0438\u0438 \u043c\u043e\u0433\u0443\u0442 \u043d\u0435\u043c\u043d\u043e\u0433\u043e \u0441\u043d\u0438\u0437\u0438\u0442\u044c \u0442\u044f\u0433\u0443 \u043a \u043f\u0440\u043e\u0440\u0430\u0431\u043e\u0442\u0430\u043d\u043d\u044b\u043c \u043f\u0440\u043e\u0434\u0443\u043a\u0442\u0430\u043c \u0438 \u043f\u043e\u043c\u043e\u0447\u044c \u043d\u0430 \u043a\u043e\u0440\u043e\u0442\u043a\u043e\u0439 \u0434\u0438\u0441\u0442\u0430\u043d\u0446\u0438\u0438, \u043d\u043e \u0443\u0441\u0442\u043e\u0439\u0447\u0438\u0432\u043e\u0433\u043e \u043e\u0431\u0449\u0435\u0433\u043e \u044d\u0444\u0444\u0435\u043a\u0442\u0430 \u043d\u0435 \u0434\u043e\u043a\u0430\u0437\u0430\u043d\u043e \u2014 \u0442\u0430\u043a \u0447\u0442\u043e \u043a \u0433\u0440\u043e\u043c\u043a\u0438\u043c \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f\u043c \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u0435\u0441\u044c \u0441\u0434\u0435\u0440\u0436\u0430\u043d\u043d\u043e.",rec:"\u0413\u043e\u043d\u0438\u0442\u0435\u0441\u044c \u0437\u0430 \u0447\u0438\u0441\u0442\u044b\u043c\u0438 \u043e\u0441\u0442\u0430\u043d\u043e\u0432\u043a\u0430\u043c\u0438, \u0430 \u043d\u0435 \u0437\u0430 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c\u044e. \u041f\u043e\u0447\u0442\u0438 \u0438\u0434\u0435\u0430\u043b\u044c\u043d\u044b\u0439 \u0437\u0430\u0445\u043e\u0434 \u0431\u0435\u0437 \u0435\u0434\u0438\u043d\u043e\u0433\u043e \u043b\u043e\u0436\u043d\u043e\u0433\u043e \u043d\u0430\u0436\u0430\u0442\u0438\u044f \u0446\u0435\u043d\u043d\u0435\u0435 \u0431\u044b\u0441\u0442\u0440\u043e\u0433\u043e, \u043d\u043e \u0443\u0441\u044b\u043f\u0430\u043d\u043d\u043e\u0433\u043e \u043e\u0448\u0438\u0431\u043a\u0430\u043c\u0438.",faq:[["\u041f\u043b\u043e\u0445\u043e \u043b\u0438 \u0438\u043d\u043e\u0433\u0434\u0430 \u043d\u0430\u0436\u0430\u0442\u044c \u043d\u0430 \xab\u043d\u0435 \u0440\u0435\u0430\u0433\u0438\u0440\u0443\u0439\xbb?","\u041e\u0442\u0434\u0435\u043b\u044c\u043d\u044b\u0439 \u0441\u0440\u044b\u0432 \u2014 \u044d\u0442\u043e \u043d\u043e\u0440\u043c\u0430\u043b\u044c\u043d\u043e \u0438 \u0434\u0430\u0436\u0435 \u043e\u0436\u0438\u0434\u0430\u0435\u043c\u043e, \u0432\u0435\u0434\u044c \u0441\u0430\u043c\u0430 \u0441\u0445\u0435\u043c\u0430 \u0434\u0435\u043b\u0430\u0435\u0442 \u043d\u0430\u0436\u0430\u0442\u0438\u0435 \u043f\u0440\u0438\u0432\u044b\u0447\u043a\u043e\u0439. \u0412\u0430\u0436\u043d\u0430 \u0434\u0438\u043d\u0430\u043c\u0438\u043a\u0430: \u0447\u0435\u043c \u043c\u0435\u043d\u044c\u0448\u0435 \u043b\u043e\u0436\u043d\u044b\u0445 \u043d\u0430\u0436\u0430\u0442\u0438\u0439 \u043e\u0442 \u043f\u043e\u0434\u0445\u043e\u0434\u0430 \u043a \u043f\u043e\u0434\u0445\u043e\u0434\u0443, \u0442\u0435\u043c \u043e\u0441\u0442\u0440\u0435\u0435 \u0432\u0430\u0448\u0435 \u0442\u043e\u0440\u043c\u043e\u0436\u0435\u043d\u0438\u0435."],["\u0421\u0434\u0435\u043b\u0430\u0435\u0442 \u043b\u0438 \u044d\u0442\u043e \u043c\u0435\u043d\u044f \u043c\u0435\u043d\u0435\u0435 \u0438\u043c\u043f\u0443\u043b\u044c\u0441\u0438\u0432\u043d\u044b\u043c \u0432 \u0436\u0438\u0437\u043d\u0438?","\u0427\u0435\u0441\u0442\u043d\u043e \u2014 \u0441\u043a\u043e\u0440\u0435\u0435 \u0432\u0441\u0435\u0433\u043e, \u043d\u0435 \u0432 \u0448\u0438\u0440\u043e\u043a\u043e\u043c \u0441\u043c\u044b\u0441\u043b\u0435. \u0412 \u0441\u0430\u043c\u043e\u0439 \u0437\u0430\u0434\u0430\u0447\u0435 \u0432\u044b \u043d\u0430\u0432\u0435\u0440\u043d\u044f\u043a\u0430 \u0441\u0442\u0430\u043d\u0435\u0442\u0435 \u043b\u0443\u0447\u0448\u0435, \u043d\u043e \u0443\u0431\u0435\u0434\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0445 \u0434\u0430\u043d\u043d\u044b\u0445, \u0447\u0442\u043e \u043d\u0430\u0432\u044b\u043a go/no-go \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0438\u0442\u0441\u044f \u043d\u0430 \u0431\u044b\u0442\u043e\u0432\u043e\u0439 \u0441\u0430\u043c\u043e\u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044c \u0438\u043b\u0438 \u0438\u043c\u043f\u0443\u043b\u044c\u0441\u0438\u0432\u043d\u043e\u0441\u0442\u044c \u0432 \u0446\u0435\u043b\u043e\u043c, \u043d\u0435\u0442."],["\u041d\u0430 \u0447\u0451\u043c \u0441\u043e\u0441\u0440\u0435\u0434\u043e\u0442\u043e\u0447\u0438\u0442\u044c\u0441\u044f \u2014 \u043d\u0430 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u0438 \u0438\u043b\u0438 \u043d\u0430 \u043e\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0438 \u043e\u0448\u0438\u0431\u043e\u043a?","\u041d\u0430 \u043e\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0438 \u043e\u0448\u0438\u0431\u043e\u043a. \u0421\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u043f\u0440\u0438\u0434\u0451\u0442 \u0441\u0430\u043c\u0430 \u0441 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u043e\u0439, \u0430 \u043d\u0430\u0441\u0442\u043e\u044f\u0449\u0438\u0439 \u043d\u0430\u0432\u044b\u043a, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u044d\u0442\u043e \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u0435, \u2014 \u0447\u0438\u0441\u0442\u043e\u0435 \u0443\u0434\u0435\u0440\u0436\u0430\u043d\u0438\u0435 \u043e\u0442\u0432\u0435\u0442\u0430 \u043d\u0430 \u0441\u0442\u043e\u043f-\u0441\u0438\u0433\u043d\u0430\u043b\u0430\u0445."]],variants:"\u0411\u043b\u0438\u0436\u0430\u0439\u0448\u0438\u0439 \u0440\u043e\u0434\u0441\u0442\u0432\u0435\u043d\u043d\u0438\u043a \u2014 \u0437\u0430\u0434\u0430\u0447\u0430 \u0441\u043e \u0441\u0442\u043e\u043f-\u0441\u0438\u0433\u043d\u0430\u043b\u043e\u043c, \u0433\u0434\u0435 \u0432\u044b \u0443\u0436\u0435 \u043d\u0430\u0447\u0430\u043b\u0438 \u043e\u0442\u0432\u0435\u0447\u0430\u0442\u044c, \u0438 \u0441\u0438\u0433\u043d\u0430\u043b \u0432\u0435\u043b\u0438\u0442 \u043e\u0431\u043e\u0440\u0432\u0430\u0442\u044c \u0434\u0432\u0438\u0436\u0435\u043d\u0438\u0435 \u043d\u0430 \u043f\u043e\u043b\u043f\u0443\u0442\u0438; \u043e\u043d\u0430 \u043f\u0440\u043e\u0432\u0435\u0440\u044f\u0435\u0442 \u043d\u0435\u043c\u043d\u043e\u0433\u043e \u0438\u043d\u043e\u0439 \u043c\u0435\u0445\u0430\u043d\u0438\u0437\u043c \u0442\u043e\u0440\u043c\u043e\u0436\u0435\u043d\u0438\u044f. \u0412 \u0434\u0440\u0443\u0433\u0438\u0445 \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u0430\u0445 \u043d\u0435\u0439\u0442\u0440\u0430\u043b\u044c\u043d\u044b\u0435 \u0441\u0438\u0433\u043d\u0430\u043b\u044b \u0437\u0430\u043c\u0435\u043d\u044f\u044e\u0442 \u043d\u0430 \u044d\u043c\u043e\u0446\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u044b\u0435 \u043b\u0438\u0446\u0430 \u0438\u043b\u0438 \u043d\u0430 \u0441\u043e\u0431\u043b\u0430\u0437\u043d\u044b \u0432\u0440\u043e\u0434\u0435 \u043a\u0430\u043b\u043e\u0440\u0438\u0439\u043d\u043e\u0439 \u0435\u0434\u044b \u0438 \u0430\u043b\u043a\u043e\u0433\u043e\u043b\u044f, \u0430 \u0441\u043b\u043e\u0436\u043d\u043e\u0441\u0442\u044c \u0447\u0430\u0441\u0442\u043e \u043f\u043e\u0434\u043d\u0438\u043c\u0430\u044e\u0442, \u0443\u0441\u043a\u043e\u0440\u044f\u044f \u0441\u0438\u0433\u043d\u0430\u043b\u044b \u0438\u043b\u0438 \u0434\u0435\u043b\u0430\u044f \u0440\u0435\u0434\u043a\u0438\u0439 \u0441\u0442\u043e\u043f \u0435\u0449\u0451 \u0431\u043e\u043b\u0435\u0435 \u0440\u0435\u0434\u043a\u0438\u043c."},en:{about:"Inhibition is a go/no-go exercise. A stream of cues flashes up one at a time, and your job is to react fast to the \"go\" cues (usually by tapping) while holding back completely on the \"no-go\" cues. Because most cues are \"go\", tapping becomes a reflex, and the challenge is catching yourself before you tap on the rare \"no-go\".",benefit:"It trains response inhibition, the part of executive control that lets you stop an action already on its way. It also leans on sustained attention, since one lapse and your finger fires on its own.",history:"The go/no-go arrangement grows out of nineteenth-century reaction-time research and became a workhorse of clinical neuropsychology in the twentieth, where failures to withhold a response were tied to frontal-lobe function. From there it spread into cognitive psychology, child development and, more recently, app-based brain training and habit-change studies for food and alcohol.",creator:"There is no single inventor. The go/no-go method descends from the reaction-time tradition usually traced to Franciscus Donders (1868), and it was shaped over the twentieth century by neuropsychologists studying impulse control and the frontal lobes rather than by one named author.",methods:"Keep your finger relaxed and ready rather than tensed to slam down, since the whole point is being able to abort. Resist the urge to chase speed at all costs, because the errors that matter here are tapping on a no-go, not being a fraction slower. As you improve, raise the pace or lower the share of no-go cues so stopping stays genuinely hard.",duration:"Short and frequent beats long and rare. Five to ten minutes a session, a few times a week, is plenty, and a single block should stay brief enough that your attention does not sag, because tired attention is what makes the no-go slip past.",research:"Evidence is solid for the obvious thing: practise and you get better at this kind of stopping task and make fewer false taps. Claims that it broadly lifts everyday self-control, curbs impulsivity in general, or sharpens unrelated thinking are far weaker. A well-known training study by Enge and colleagues (2014) found no genuine transfer beyond the trained tasks, and a 2024 study in children reported that targeted response-inhibition training did little to change their brains or behaviour. Food-specific versions can nudge down intake of the trained foods and help short-term, but lasting, general effects are not established, so treat the big promises with caution.",rec:"Chase clean stops, not raw speed. A near-perfect run with zero false taps beats a fast run littered with them.",faq:[["Is it bad to occasionally tap on a no-go?","An occasional slip is normal and even expected, because the design makes tapping habitual. What matters is the trend: fewer false taps over sessions means your stopping is getting sharper."],["Will this make me less impulsive in real life?","Honestly, probably not in a broad way. You will reliably get better at the task itself, but strong evidence that go/no-go practice transfers to everyday self-control or general impulsivity is lacking."],["Should I focus on going faster or on not making mistakes?","On not making mistakes. Speed comes on its own with practice, while the skill this exercise actually trains is the clean withholding of a response on no-go cues."]],variants:"The close cousin is the stop-signal task, where you have already started responding and a signal tells you to abort mid-action, which probes a slightly different braking mechanism. Other variants swap neutral cues for emotional faces or for tempting items like high-calorie food or alcohol, and many add difficulty by speeding the cues up or making the rare no-go even rarer."},es:{about:"Inhibici\xf3n es un ejercicio de tipo go/no-go. Una corriente de se\xf1ales aparece de una en una, y tu tarea es reaccionar r\xe1pido a las se\xf1ales \"go\" (normalmente tocando) mientras te frenas por completo ante las se\xf1ales \"no-go\". Como la mayor\xeda de las se\xf1ales son \"go\", tocar se vuelve un reflejo, y el reto es pillarte a ti mismo antes de tocar en la rara se\xf1al \"no-go\".",benefit:"Entrena la inhibici\xf3n de respuestas, la parte del control ejecutivo que te permite detener una acci\xf3n ya en marcha. Tambi\xe9n se apoya en la atenci\xf3n sostenida, ya que basta un descuido y tu dedo se dispara solo.",history:"El esquema go/no-go surge de la investigaci\xf3n sobre tiempos de reacci\xf3n del siglo XIX y se volvi\xf3 un caballo de batalla de la neuropsicolog\xeda cl\xednica en el XX, donde los fallos para retener una respuesta se vinculaban con la funci\xf3n del l\xf3bulo frontal. De ah\xed se extendi\xf3 a la psicolog\xeda cognitiva, al desarrollo infantil y, m\xe1s recientemente, al entrenamiento mental en apps y a los estudios de cambio de h\xe1bitos para la comida y el alcohol.",creator:"No hay un \xfanico inventor. El m\xe9todo go/no-go desciende de la tradici\xf3n de los tiempos de reacci\xf3n que suele remontarse a Franciscus Donders (1868), y a lo largo del siglo XX lo moldearon los neuropsic\xf3logos que estudiaban el control de los impulsos y los l\xf3bulos frontales, m\xe1s que un autor concreto.",methods:"Mant\xe9n el dedo relajado y listo en lugar de tenso para machacar, ya que todo el prop\xf3sito es ser capaz de abortar. Resiste la tentaci\xf3n de perseguir la velocidad a toda costa, porque los errores que importan aqu\xed son tocar en un no-go, no ser una fracci\xf3n m\xe1s lento. A medida que mejoras, sube el ritmo o reduce la proporci\xf3n de se\xf1ales no-go para que detenerte siga siendo realmente dif\xedcil.",duration:"Corto y frecuente supera a largo y espor\xe1dico. De cinco a diez minutos por sesi\xf3n, unas cuantas veces por semana, es suficiente, y un solo bloque debe mantenerse lo bastante breve como para que tu atenci\xf3n no decaiga, porque la atenci\xf3n cansada es lo que hace que el no-go se cuele.",research:"La evidencia es s\xf3lida para lo evidente: practicas y mejoras en este tipo de tarea de detenci\xf3n y cometes menos toques falsos. Las afirmaciones de que eleva de forma amplia el autocontrol cotidiano, frena la impulsividad en general o afila el pensamiento no relacionado son mucho m\xe1s d\xe9biles. Un conocido estudio de entrenamiento de Enge y colaboradores (2014) no encontr\xf3 transferencia genuina m\xe1s all\xe1 de las tareas entrenadas, y un estudio de 2024 en ni\xf1os inform\xf3 de que el entrenamiento dirigido de inhibici\xf3n de respuestas hizo poco por cambiar su cerebro o su conducta. Las versiones espec\xedficas de comida pueden reducir un poco el consumo de los alimentos entrenados y ayudar a corto plazo, pero no se han establecido efectos duraderos y generales, as\xed que toma con cautela las grandes promesas.",rec:"Persigue detenciones limpias, no velocidad pura. Una ronda casi perfecta con cero toques falsos supera a una ronda r\xe1pida plagada de ellos.",faq:[["\xbfEs malo tocar de vez en cuando en un no-go?","Un desliz ocasional es normal e incluso esperable, porque el dise\xf1o hace que tocar sea habitual. Lo que importa es la tendencia: menos toques falsos a lo largo de las sesiones significa que tu freno se est\xe1 afilando."],["\xbfEsto me har\xe1 menos impulsivo en la vida real?","Sinceramente, probablemente no de forma amplia. Mejorar\xe1s de forma fiable en la tarea en s\xed, pero falta evidencia s\xf3lida de que la pr\xe1ctica go/no-go se transfiera al autocontrol cotidiano o a la impulsividad general."],["\xbfDebo centrarme en ir m\xe1s r\xe1pido o en no cometer errores?","En no cometer errores. La velocidad llega sola con la pr\xe1ctica, mientras que la habilidad que este ejercicio entrena de verdad es la retenci\xf3n limpia de una respuesta ante las se\xf1ales no-go."]],variants:"El primo cercano es la tarea de se\xf1al de parada (stop-signal), en la que ya has empezado a responder y una se\xf1al te dice que abortes a mitad de la acci\xf3n, lo que sondea un mecanismo de frenado algo distinto. Otras variantes cambian las se\xf1ales neutras por caras emocionales o por elementos tentadores como comida muy cal\xf3rica o alcohol, y muchas a\xf1aden dificultad acelerando las se\xf1ales o haciendo el raro no-go a\xfan m\xe1s raro."},de:{about:"Inhibition ist eine Go/No-Go-\xdcbung. Ein Strom von Reizen blitzt einer nach dem anderen auf, und deine Aufgabe ist es, schnell auf die \"Go\"-Reize zu reagieren (meist durch Tippen), w\xe4hrend du bei den \"No-Go\"-Reizen vollst\xe4ndig inneh\xe4ltst. Weil die meisten Reize \"Go\" sind, wird das Tippen zum Reflex, und die Herausforderung besteht darin, sich vor dem Tippen beim seltenen \"No-Go\" selbst zu erwischen.",benefit:"Es trainiert die Reaktionshemmung, jenen Teil der exekutiven Kontrolle, der dich eine bereits anlaufende Handlung stoppen l\xe4sst. Es st\xfctzt sich au\xdferdem auf die Daueraufmerksamkeit, denn ein einziger Aussetzer, und dein Finger feuert von selbst.",history:"Die Go/No-Go-Anordnung erw\xe4chst aus der Reaktionszeitforschung des 19. Jahrhunderts und wurde im 20. Jahrhundert zum Arbeitspferd der klinischen Neuropsychologie, wo das Versagen, eine Reaktion zur\xfcckzuhalten, mit der Stirnlappenfunktion verkn\xfcpft wurde. Von dort verbreitete sie sich in die kognitive Psychologie, die Entwicklungspsychologie des Kindes und, in j\xfcngerer Zeit, in app-basiertes Gehirntraining sowie Studien zur Gewohnheits\xe4nderung bei Essen und Alkohol.",creator:"Es gibt keinen einzelnen Erfinder. Die Go/No-Go-Methode stammt aus der Reaktionszeit-Tradition, die \xfcblicherweise auf Franciscus Donders (1868) zur\xfcckgef\xfchrt wird, und sie wurde \xfcber das 20. Jahrhundert von Neuropsychologen geformt, die Impulskontrolle und die Stirnlappen untersuchten, und nicht von einem einzelnen benannten Urheber.",methods:"Halte deinen Finger entspannt und bereit, statt ihn angespannt zum Zuschlagen zu halten, denn der ganze Sinn ist die F\xe4higkeit abzubrechen. Widerstehe dem Drang, um jeden Preis dem Tempo nachzujagen, denn die Fehler, die hier z\xe4hlen, sind das Tippen bei einem No-Go, nicht ein Sekundenbruchteil langsamer zu sein. Wenn du besser wirst, erh\xf6he das Tempo oder senke den Anteil der No-Go-Reize, damit das Stoppen wirklich schwer bleibt.",duration:"Kurz und h\xe4ufig schl\xe4gt lang und selten. F\xfcnf bis zehn Minuten pro Einheit, ein paar Mal pro Woche, reichen v\xf6llig, und ein einzelner Block sollte kurz genug bleiben, dass deine Aufmerksamkeit nicht nachl\xe4sst, denn m\xfcde Aufmerksamkeit ist das, was das No-Go durchrutschen l\xe4sst.",research:"Die Belege sind solide f\xfcr das Naheliegende: \xdcbe, und du wirst besser bei dieser Art Stopp-Aufgabe und machst weniger Fehltipper. Behauptungen, dass es die allt\xe4gliche Selbstkontrolle breit hebt, die Impulsivit\xe4t allgemein z\xfcgelt oder unverwandtes Denken sch\xe4rft, sind weit schw\xe4cher. Eine bekannte Trainingsstudie von Enge und Kollegen (2014) fand keinen echten Transfer \xfcber die trainierten Aufgaben hinaus, und eine Studie von 2024 mit Kindern berichtete, dass gezieltes Reaktionshemmungstraining ihr Gehirn oder Verhalten kaum ver\xe4nderte. Nahrungsspezifische Versionen k\xf6nnen den Verzehr der trainierten Lebensmittel etwas senken und kurzfristig helfen, aber anhaltende, allgemeine Effekte sind nicht belegt, also begegne den gro\xdfen Versprechen mit Vorsicht.",rec:"Jage sauberen Stopps nach, nicht rohem Tempo. Ein nahezu perfekter Durchlauf mit null Fehltippern schl\xe4gt einen schnellen Durchlauf, der davon \xfcbers\xe4t ist.",faq:[["Ist es schlimm, gelegentlich bei einem No-Go zu tippen?","Ein gelegentlicher Ausrutscher ist normal und sogar zu erwarten, weil das Design das Tippen zur Gewohnheit macht. Was z\xe4hlt, ist der Trend: weniger Fehltipper \xfcber die Einheiten hinweg bedeutet, dass dein Stoppen sch\xe4rfer wird."],["Macht mich das im echten Leben weniger impulsiv?","Ehrlich gesagt, wohl nicht in breitem Ma\xdf. Du wirst zuverl\xe4ssig besser bei der Aufgabe selbst, aber ein starker Beleg daf\xfcr, dass Go/No-Go-\xdcbung sich auf die allt\xe4gliche Selbstkontrolle oder allgemeine Impulsivit\xe4t \xfcbertr\xe4gt, fehlt."],["Soll ich mich darauf konzentrieren, schneller zu werden, oder keine Fehler zu machen?","Darauf, keine Fehler zu machen. Tempo kommt mit der \xdcbung von selbst, w\xe4hrend die F\xe4higkeit, die diese \xdcbung tats\xe4chlich trainiert, das saubere Zur\xfcckhalten einer Reaktion bei No-Go-Reizen ist."]],variants:"Der nahe Verwandte ist die Stopp-Signal-Aufgabe, bei der du bereits zu reagieren begonnen hast und ein Signal dir sagt, mitten in der Handlung abzubrechen, was einen leicht anderen Bremsmechanismus pr\xfcft. Andere Varianten tauschen neutrale Reize gegen emotionale Gesichter oder gegen verlockende Dinge wie kalorienreiches Essen oder Alkohol, und viele erh\xf6hen die Schwierigkeit, indem sie die Reize beschleunigen oder das seltene No-Go noch seltener machen."},pt:{about:"Inibi\xe7\xe3o \xe9 um exerc\xedcio de vai/n\xe3o vai (go/no-go). Uma sequ\xeancia de pistas pisca uma de cada vez, e sua tarefa \xe9 reagir r\xe1pido \xe0s pistas \"vai\" (geralmente tocando) enquanto se segura por completo nas pistas \"n\xe3o vai\". Como a maioria das pistas \xe9 \"vai\", tocar vira um reflexo, e o desafio \xe9 se conter antes de tocar na rara pista \"n\xe3o vai\".",benefit:"Ele treina a inibi\xe7\xe3o de resposta, a parte do controle executivo que permite interromper uma a\xe7\xe3o j\xe1 a caminho. Tamb\xe9m se apoia na aten\xe7\xe3o sustentada, pois basta um cochilo e seu dedo dispara sozinho.",history:"O arranjo vai/n\xe3o vai nasceu da pesquisa de tempo de rea\xe7\xe3o do s\xe9culo XIX e virou um cavalo de batalha da neuropsicologia cl\xednica no s\xe9culo XX, em que falhas em conter uma resposta foram associadas ao funcionamento do lobo frontal. De l\xe1, espalhou-se para a psicologia cognitiva, o desenvolvimento infantil e, mais recentemente, o treino cerebral em aplicativos e os estudos de mudan\xe7a de h\xe1bito para comida e \xe1lcool.",creator:"N\xe3o h\xe1 um \xfanico inventor. O m\xe9todo vai/n\xe3o vai descende da tradi\xe7\xe3o de tempo de rea\xe7\xe3o, em geral atribu\xedda a Franciscus Donders (1868), e foi moldado ao longo do s\xe9culo XX por neuropsic\xf3logos que estudavam o controle de impulsos e os lobos frontais, e n\xe3o por um \xfanico autor com nome pr\xf3prio.",methods:"Mantenha o dedo relaxado e pronto, em vez de tenso para se lan\xe7ar para baixo, j\xe1 que toda a gra\xe7a \xe9 conseguir abortar. Resista \xe0 vontade de perseguir velocidade a todo custo, porque os erros que importam aqui s\xe3o tocar num \"n\xe3o vai\", e n\xe3o ser uma fra\xe7\xe3o mais lento. Conforme voc\xea melhora, aumente o ritmo ou diminua a propor\xe7\xe3o de pistas \"n\xe3o vai\" para que se conter continue genuinamente dif\xedcil.",duration:"Curto e frequente bate longo e raro. De cinco a dez minutos por sess\xe3o, algumas vezes por semana, j\xe1 basta, e um \xfanico bloco deve ser breve o bastante para que sua aten\xe7\xe3o n\xe3o caia, porque \xe9 a aten\xe7\xe3o cansada que faz o \"n\xe3o vai\" passar batido.",research:"As evid\xeancias s\xe3o s\xf3lidas para o \xf3bvio: pratique e voc\xea fica melhor nesse tipo de tarefa de conten\xe7\xe3o e d\xe1 menos toques indevidos. Alega\xe7\xf5es de que isso eleva amplamente o autocontrole do dia a dia, refreia a impulsividade em geral ou afia racioc\xednios n\xe3o relacionados s\xe3o bem mais fracas. Um conhecido estudo de treino de Enge e colaboradores (2014) n\xe3o encontrou transfer\xeancia genu\xedna al\xe9m das tarefas treinadas, e um estudo de 2024 com crian\xe7as relatou que o treino direcionado de inibi\xe7\xe3o de resposta pouco mudou seus c\xe9rebros ou comportamentos. Vers\xf5es espec\xedficas para comida podem reduzir um pouco o consumo dos alimentos treinados e ajudar no curto prazo, mas efeitos duradouros e gerais n\xe3o est\xe3o estabelecidos, ent\xe3o trate as grandes promessas com cautela.",rec:"Persiga conten\xe7\xf5es limpas, n\xe3o velocidade pura. Uma rodada quase perfeita com zero toques indevidos vale mais que uma rodada r\xe1pida cheia deles.",faq:[["\xc9 ruim tocar de vez em quando num \"n\xe3o vai\"?","Um deslize ocasional \xe9 normal e at\xe9 esperado, porque o desenho torna o toque habitual. O que importa \xe9 a tend\xeancia: menos toques indevidos ao longo das sess\xf5es significa que sua conten\xe7\xe3o est\xe1 ficando mais afiada."],["Isso vai me deixar menos impulsivo na vida real?","Honestamente, provavelmente n\xe3o de forma ampla. Voc\xea vai ficar de modo confi\xe1vel melhor na pr\xf3pria tarefa, mas faltam evid\xeancias fortes de que praticar vai/n\xe3o vai se transfira para o autocontrole do dia a dia ou para a impulsividade geral."],["Devo focar em ir mais r\xe1pido ou em n\xe3o errar?","Em n\xe3o errar. A velocidade vem sozinha com a pr\xe1tica, ao passo que a habilidade que este exerc\xedcio de fato treina \xe9 a conten\xe7\xe3o limpa de uma resposta nas pistas \"n\xe3o vai\"."]],variants:"O primo pr\xf3ximo \xe9 a tarefa de sinal de parada (stop-signal), em que voc\xea j\xe1 come\xe7ou a responder e um sinal manda abortar no meio da a\xe7\xe3o, o que sonda um mecanismo de frenagem um pouco diferente. Outras variantes trocam as pistas neutras por rostos com emo\xe7\xe3o ou por itens tentadores, como comida cal\xf3rica ou \xe1lcool, e muitas aumentam a dificuldade acelerando as pistas ou tornando o raro \"n\xe3o vai\" ainda mais raro."},hi:{about:"Inhibition \u090f\u0915 go/no-go \u0915\u0938\u0930\u0924 \u0939\u0948\u0964 \u0938\u0902\u0915\u0947\u0924\u094b\u0902 \u0915\u0940 \u090f\u0915 \u0927\u093e\u0930\u093e \u090f\u0915-\u090f\u0915 \u0915\u0930\u0915\u0947 \u091a\u092e\u0915\u0924\u0940 \u0939\u0948, \u0914\u0930 \u0906\u092a\u0915\u093e \u0915\u093e\u092e \"go\" \u0938\u0902\u0915\u0947\u0924\u094b\u0902 \u092a\u0930 \u0924\u0947\u091c\u093c\u0940 \u0938\u0947 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0926\u0947\u0928\u093e (\u0906\u092e\u0924\u094c\u0930 \u092a\u0930 \u091f\u0948\u092a \u0915\u0930\u0915\u0947) \u0914\u0930 \"no-go\" \u0938\u0902\u0915\u0947\u0924\u094b\u0902 \u092a\u0930 \u092a\u0942\u0930\u0940 \u0924\u0930\u0939 \u0930\u0941\u0915 \u091c\u093e\u0928\u093e \u0939\u0948\u0964 \u091a\u0942\u0901\u0915\u093f \u091c\u093c\u094d\u092f\u093e\u0926\u093e\u0924\u0930 \u0938\u0902\u0915\u0947\u0924 \"go\" \u0939\u094b\u0924\u0947 \u0939\u0948\u0902, \u091f\u0948\u092a \u0915\u0930\u0928\u093e \u090f\u0915 \u092a\u094d\u0930\u0924\u093f\u0935\u0930\u094d\u0924 \u092c\u0928 \u091c\u093e\u0924\u093e \u0939\u0948, \u0914\u0930 \u091a\u0941\u0928\u094c\u0924\u0940 \u0939\u0948 \u0915\u093f \u0915\u093f\u0938\u0940 \u0935\u093f\u0930\u0932 \"no-go\" \u092a\u0930 \u091f\u0948\u092a \u0915\u0930\u0928\u0947 \u0938\u0947 \u092a\u0939\u0932\u0947 \u0906\u092a \u0916\u093c\u0941\u0926 \u0915\u094b \u0925\u093e\u092e \u0932\u0947\u0902\u0964",benefit:"\u092f\u0939 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0905\u0935\u0930\u094b\u0927\u0928 \u0915\u094b \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u093f\u0924 \u0915\u0930\u0924\u093e \u0939\u0948, \u0915\u093e\u0930\u094d\u092f\u0915\u093e\u0930\u0940 \u0928\u093f\u092f\u0902\u0924\u094d\u0930\u0923 \u0915\u093e \u0935\u0939 \u0939\u093f\u0938\u094d\u0938\u093e \u091c\u094b \u0906\u092a\u0915\u094b \u092a\u0939\u0932\u0947 \u0938\u0947 \u0936\u0941\u0930\u0942 \u0939\u094b \u091a\u0941\u0915\u0940 \u0915\u093f\u0938\u0940 \u0915\u094d\u0930\u093f\u092f\u093e \u0915\u094b \u0930\u094b\u0915\u0928\u0947 \u0926\u0947\u0924\u093e \u0939\u0948\u0964 \u092f\u0939 \u0938\u0924\u0924 \u0927\u094d\u092f\u093e\u0928 \u092a\u0930 \u092d\u0940 \u091f\u093f\u0915\u093e \u0939\u0948, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u090f\u0915 \u091a\u0942\u0915 \u0914\u0930 \u0906\u092a\u0915\u0940 \u0909\u0901\u0917\u0932\u0940 \u0905\u092a\u0928\u0947 \u0906\u092a \u091a\u0932 \u092a\u0921\u093c\u0924\u0940 \u0939\u0948\u0964",history:"go/no-go \u0935\u094d\u092f\u0935\u0938\u094d\u0925\u093e \u0909\u0928\u094d\u0928\u0940\u0938\u0935\u0940\u0902 \u0938\u0926\u0940 \u0915\u0947 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0938\u092e\u092f \u0936\u094b\u0927 \u0938\u0947 \u0928\u093f\u0915\u0932\u0940 \u0914\u0930 \u092c\u0940\u0938\u0935\u0940\u0902 \u0938\u0926\u0940 \u092e\u0947\u0902 \u0928\u0948\u0926\u093e\u0928\u093f\u0915 \u0924\u0902\u0924\u094d\u0930\u093f\u0915\u093e-\u092e\u0928\u094b\u0935\u093f\u091c\u094d\u091e\u093e\u0928 \u0915\u093e \u090f\u0915 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0914\u091c\u093c\u093e\u0930 \u092c\u0928 \u0917\u0908, \u091c\u0939\u093e\u0901 \u0915\u093f\u0938\u0940 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0915\u094b \u0930\u094b\u0915 \u0928 \u092a\u093e\u0928\u0947 \u0915\u094b \u092b\u094d\u0930\u0902\u091f\u0932-\u0932\u094b\u092c \u0915\u0947 \u0915\u093e\u092e \u0938\u0947 \u091c\u094b\u0921\u093c\u093e \u0917\u092f\u093e\u0964 \u0935\u0939\u093e\u0901 \u0938\u0947 \u092f\u0939 \u0938\u0902\u091c\u094d\u091e\u093e\u0928\u093e\u0924\u094d\u092e\u0915 \u092e\u0928\u094b\u0935\u093f\u091c\u094d\u091e\u093e\u0928, \u092c\u093e\u0932 \u0935\u093f\u0915\u093e\u0938 \u0914\u0930 \u0939\u093e\u0932 \u0939\u0940 \u092e\u0947\u0902 \u0910\u092a-\u0906\u0927\u093e\u0930\u093f\u0924 \u0926\u093f\u092e\u093e\u0917\u0940 \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u0924\u0925\u093e \u092d\u094b\u091c\u0928 \u0914\u0930 \u0936\u0930\u093e\u092c \u0915\u0947 \u0932\u093f\u090f \u0906\u0926\u0924-\u092c\u0926\u0932\u0928\u0947 \u0935\u093e\u0932\u0947 \u0905\u0927\u094d\u092f\u092f\u0928\u094b\u0902 \u092e\u0947\u0902 \u092b\u0948\u0932 \u0917\u0908\u0964",creator:"\u0907\u0938\u0915\u093e \u0915\u094b\u0908 \u090f\u0915 \u0906\u0935\u093f\u0937\u094d\u0915\u093e\u0930\u0915 \u0928\u0939\u0940\u0902 \u0939\u0948\u0964 go/no-go \u0935\u093f\u0927\u093f \u0909\u0938 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0938\u092e\u092f \u092a\u0930\u0902\u092a\u0930\u093e \u0938\u0947 \u0909\u0924\u0930\u0940 \u0939\u0948 \u091c\u093f\u0938\u0947 \u0906\u092e\u0924\u094c\u0930 \u092a\u0930 Franciscus Donders (1868) \u0924\u0915 \u091c\u094b\u0921\u093c\u093e \u091c\u093e\u0924\u093e \u0939\u0948, \u0914\u0930 \u0907\u0938\u0947 \u092c\u0940\u0938\u0935\u0940\u0902 \u0938\u0926\u0940 \u0915\u0947 \u0926\u094c\u0930\u093e\u0928 \u0915\u093f\u0938\u0940 \u090f\u0915 \u0928\u093e\u092e\u093f\u0924 \u0932\u0947\u0916\u0915 \u0928\u0947 \u0928\u0939\u0940\u0902, \u092c\u0932\u094d\u0915\u093f \u0906\u0935\u0947\u0917-\u0928\u093f\u092f\u0902\u0924\u094d\u0930\u0923 \u0914\u0930 \u092b\u094d\u0930\u0902\u091f\u0932 \u0932\u094b\u092c \u0915\u093e \u0905\u0927\u094d\u092f\u092f\u0928 \u0915\u0930\u0928\u0947 \u0935\u093e\u0932\u0947 \u0924\u0902\u0924\u094d\u0930\u093f\u0915\u093e-\u092e\u0928\u094b\u0935\u0948\u091c\u094d\u091e\u093e\u0928\u093f\u0915\u094b\u0902 \u0928\u0947 \u0917\u0922\u093c\u093e\u0964",methods:"\u0905\u092a\u0928\u0940 \u0909\u0901\u0917\u0932\u0940 \u0915\u094b \u0926\u092c\u093e\u0935 \u0938\u0947 \u0920\u094b\u0902\u0915\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0915\u0938\u0940 \u0930\u0916\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u0922\u0940\u0932\u0940 \u0914\u0930 \u0924\u0948\u092f\u093e\u0930 \u0930\u0916\u0947\u0902, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u092a\u0942\u0930\u093e \u092e\u0915\u0938\u0926 \u0939\u0940 \u0915\u094d\u0930\u093f\u092f\u093e \u0915\u094b \u0930\u094b\u0915 \u092a\u093e\u0928\u093e \u0939\u0948\u0964 \u0939\u0930 \u0939\u093e\u0932 \u092e\u0947\u0902 \u0930\u092b\u093c\u094d\u0924\u093e\u0930 \u0915\u093e \u092a\u0940\u091b\u093e \u0915\u0930\u0928\u0947 \u0915\u0940 \u0932\u0932\u0915 \u0915\u094b \u0930\u094b\u0915\u0947\u0902, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u092f\u0939\u093e\u0901 \u091c\u094b \u0917\u0932\u0924\u093f\u092f\u093e\u0901 \u092e\u093e\u092f\u0928\u0947 \u0930\u0916\u0924\u0940 \u0939\u0948\u0902 \u0935\u0947 \u0915\u093f\u0938\u0940 no-go \u092a\u0930 \u091f\u0948\u092a \u0915\u0930\u0928\u093e \u0939\u0948\u0902, \u0928 \u0915\u093f \u091c\u093c\u0930\u093e-\u0938\u093e \u0927\u0940\u092e\u0947 \u0939\u094b\u0928\u093e\u0964 \u091c\u0948\u0938\u0947-\u091c\u0948\u0938\u0947 \u0906\u092a \u0938\u0941\u0927\u0930\u0947\u0902, \u0930\u092b\u093c\u094d\u0924\u093e\u0930 \u092c\u0922\u093c\u093e\u090f\u0901 \u092f\u093e no-go \u0938\u0902\u0915\u0947\u0924\u094b\u0902 \u0915\u093e \u0939\u093f\u0938\u094d\u0938\u093e \u0918\u091f\u093e\u090f\u0901 \u0924\u093e\u0915\u093f \u0930\u0941\u0915\u0928\u093e \u0938\u091a\u092e\u0941\u091a \u0915\u0920\u093f\u0928 \u092c\u0928\u093e \u0930\u0939\u0947\u0964",duration:"\u091b\u094b\u091f\u093e \u0914\u0930 \u092c\u093e\u0930-\u092c\u093e\u0930, \u0932\u0902\u092c\u0947 \u0914\u0930 \u0915\u092d\u0940-\u0915\u092d\u093e\u0930 \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u0939\u0948\u0964 \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u0915\u0941\u091b \u092c\u093e\u0930, \u0939\u0930 \u0938\u0924\u094d\u0930 \u092a\u093e\u0901\u091a \u0938\u0947 \u0926\u0938 \u092e\u093f\u0928\u091f \u0915\u093e\u092b\u093c\u0940 \u0939\u0948, \u0914\u0930 \u090f\u0915 \u0939\u0940 \u092c\u094d\u0932\u0949\u0915 \u0907\u0924\u0928\u093e \u091b\u094b\u091f\u093e \u0930\u0939\u0947 \u0915\u093f \u0906\u092a\u0915\u093e \u0927\u094d\u092f\u093e\u0928 \u0928 \u0922\u0932\u0947, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u0925\u0915\u093e \u0939\u0941\u0906 \u0927\u094d\u092f\u093e\u0928 \u0939\u0940 no-go \u0915\u094b \u0928\u093f\u0915\u0932 \u091c\u093e\u0928\u0947 \u0926\u0947\u0924\u093e \u0939\u0948\u0964",research:"\u092a\u094d\u0930\u092e\u093e\u0923 \u0909\u0938 \u091c\u093c\u093e\u0939\u093f\u0930 \u092c\u093e\u0924 \u0915\u0947 \u0932\u093f\u090f \u0920\u094b\u0938 \u0939\u0948\u0902: \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0940\u091c\u093f\u090f \u0914\u0930 \u0906\u092a \u0907\u0938 \u0924\u0930\u0939 \u0915\u0947 \u0930\u094b\u0915\u0928\u0947 \u0935\u093e\u0932\u0947 \u0915\u093e\u0930\u094d\u092f \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902 \u0914\u0930 \u0915\u092e \u0917\u0932\u0924 \u091f\u0948\u092a \u0915\u0930\u0924\u0947 \u0939\u0948\u0902\u0964 \u092f\u0947 \u0926\u093e\u0935\u0947 \u0915\u093f \u092f\u0939 \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0947 \u0906\u0924\u094d\u092e-\u0928\u093f\u092f\u0902\u0924\u094d\u0930\u0923 \u0915\u094b \u0935\u094d\u092f\u093e\u092a\u0915 \u0930\u0942\u092a \u0938\u0947 \u092c\u0922\u093c\u093e\u0924\u093e \u0939\u0948, \u0906\u0935\u0947\u0917\u0936\u0940\u0932\u0924\u093e \u0915\u094b \u0906\u092e\u0924\u094c\u0930 \u092a\u0930 \u0930\u094b\u0915\u0924\u093e \u0939\u0948, \u092f\u093e \u0905\u0938\u0902\u092c\u0902\u0927\u093f\u0924 \u0938\u094b\u091a \u0915\u094b \u0924\u0947\u091c\u093c \u0915\u0930\u0924\u093e \u0939\u0948, \u0915\u0939\u0940\u0902 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0915\u092e\u091c\u093c\u094b\u0930 \u0939\u0948\u0902\u0964 Enge \u0914\u0930 \u0938\u093e\u0925\u093f\u092f\u094b\u0902 (2014) \u0915\u0947 \u090f\u0915 \u092e\u0936\u0939\u0942\u0930 \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u0905\u0927\u094d\u092f\u092f\u0928 \u0928\u0947 \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u093f\u0924 \u0915\u093e\u0930\u094d\u092f\u094b\u0902 \u0938\u0947 \u092a\u0930\u0947 \u0915\u094b\u0908 \u0905\u0938\u0932\u0940 \u0939\u0938\u094d\u0924\u093e\u0902\u0924\u0930\u0923 \u0928\u0939\u0940\u0902 \u092a\u093e\u092f\u093e, \u0914\u0930 \u092c\u091a\u094d\u091a\u094b\u0902 \u092a\u0930 2024 \u0915\u0947 \u090f\u0915 \u0905\u0927\u094d\u092f\u092f\u0928 \u0928\u0947 \u092c\u0924\u093e\u092f\u093e \u0915\u093f \u0932\u0915\u094d\u0937\u093f\u0924 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0905\u0935\u0930\u094b\u0927\u0928 \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u0928\u0947 \u0909\u0928\u0915\u0947 \u092e\u0938\u094d\u0924\u093f\u0937\u094d\u0915 \u092f\u093e \u0935\u094d\u092f\u0935\u0939\u093e\u0930 \u092e\u0947\u0902 \u092c\u0939\u0941\u0924 \u0915\u092e \u092c\u0926\u0932\u093e\u0935 \u0915\u093f\u092f\u093e\u0964 \u092d\u094b\u091c\u0928-\u0935\u093f\u0936\u093f\u0937\u094d\u091f \u0930\u0942\u092a \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u093f\u0924 \u092d\u094b\u091c\u0928\u094b\u0902 \u0915\u093e \u0938\u0947\u0935\u0928 \u0915\u0941\u091b \u0915\u092e \u0915\u0930 \u0938\u0915\u0924\u0947 \u0939\u0948\u0902 \u0914\u0930 \u0905\u0932\u094d\u092a\u0915\u093e\u0932 \u092e\u0947\u0902 \u092e\u0926\u0926 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902, \u092a\u0930 \u091f\u093f\u0915\u093e\u090a, \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u0905\u0938\u0930 \u0938\u093f\u0926\u094d\u0927 \u0928\u0939\u0940\u0902 \u0939\u0948\u0902, \u0907\u0938\u0932\u093f\u090f \u092c\u0921\u093c\u0947-\u092c\u0921\u093c\u0947 \u0935\u093e\u0926\u094b\u0902 \u0915\u094b \u0938\u093e\u0935\u0927\u093e\u0928\u0940 \u0938\u0947 \u0932\u0947\u0902\u0964",rec:"\u0938\u093e\u092b\u093c-\u0938\u0941\u0925\u0930\u0947 \u0930\u0941\u0915\u093e\u0935\u094b\u0902 \u0915\u093e \u092a\u0940\u091b\u093e \u0915\u0930\u0947\u0902, \u0915\u094b\u0930\u0940 \u0930\u092b\u093c\u094d\u0924\u093e\u0930 \u0915\u093e \u0928\u0939\u0940\u0902\u0964 \u0936\u0942\u0928\u094d\u092f \u0917\u0932\u0924 \u091f\u0948\u092a \u0935\u093e\u0932\u0940 \u0915\u0930\u0940\u092c-\u0915\u0930\u0940\u092c \u092c\u0947\u0926\u093e\u0917\u093c \u0926\u094c\u0921\u093c, \u0909\u0928\u0938\u0947 \u0905\u091f\u0940 \u092a\u0921\u093c\u0940 \u0924\u0947\u091c\u093c \u0926\u094c\u0921\u093c \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u0939\u0948\u0964",faq:[["\u0915\u094d\u092f\u093e \u0915\u092d\u0940-\u0915\u092d\u093e\u0930 \u0915\u093f\u0938\u0940 no-go \u092a\u0930 \u091f\u0948\u092a \u0915\u0930 \u092c\u0948\u0920\u0928\u093e \u092c\u0941\u0930\u093e \u0939\u0948?","\u0915\u092d\u0940-\u0915\u092d\u093e\u0930 \u0915\u0940 \u091a\u0942\u0915 \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u0939\u0948 \u0914\u0930 \u0905\u092a\u0947\u0915\u094d\u0937\u093f\u0924 \u092d\u0940, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u092c\u0928\u093e\u0935\u091f \u0939\u0940 \u091f\u0948\u092a \u0915\u0930\u0928\u093e \u0906\u0926\u0924\u0928 \u092c\u0928\u093e \u0926\u0947\u0924\u0940 \u0939\u0948\u0964 \u091c\u094b \u092e\u093e\u092f\u0928\u0947 \u0930\u0916\u0924\u093e \u0939\u0948 \u0935\u0939 \u0930\u0941\u091d\u093e\u0928 \u0939\u0948: \u0938\u0924\u094d\u0930-\u0926\u0930-\u0938\u0924\u094d\u0930 \u0915\u092e \u0917\u0932\u0924 \u091f\u0948\u092a \u0915\u093e \u092e\u0924\u0932\u092c \u0939\u0948 \u0915\u093f \u0906\u092a\u0915\u093e \u0930\u0941\u0915\u0928\u093e \u0924\u0947\u091c\u093c \u0939\u094b \u0930\u0939\u093e \u0939\u0948\u0964"],["\u0915\u094d\u092f\u093e \u0907\u0938\u0938\u0947 \u092e\u0948\u0902 \u0905\u0938\u0932 \u091c\u093c\u093f\u0902\u0926\u0917\u0940 \u092e\u0947\u0902 \u0915\u092e \u0906\u0935\u0947\u0917\u0936\u0940\u0932 \u092c\u0928 \u091c\u093e\u090a\u0901\u0917\u093e?","\u0938\u091a \u0915\u0939\u0947\u0902 \u0924\u094b \u0915\u093f\u0938\u0940 \u0935\u094d\u092f\u093e\u092a\u0915 \u0922\u0902\u0917 \u0938\u0947 \u0936\u093e\u092f\u0926 \u0928\u0939\u0940\u0902\u0964 \u0906\u092a \u0916\u093c\u0941\u0926 \u0907\u0938 \u0915\u093e\u0930\u094d\u092f \u092e\u0947\u0902 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0930\u0942\u092a \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u090f\u0901\u0917\u0947, \u092a\u0930 \u0907\u0938\u0915\u093e \u092e\u091c\u093c\u092c\u0942\u0924 \u092a\u094d\u0930\u092e\u093e\u0923 \u0915\u093f go/no-go \u0905\u092d\u094d\u092f\u093e\u0938 \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0947 \u0906\u0924\u094d\u092e-\u0928\u093f\u092f\u0902\u0924\u094d\u0930\u0923 \u092f\u093e \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u0906\u0935\u0947\u0917\u0936\u0940\u0932\u0924\u093e \u0924\u0915 \u092a\u0939\u0941\u0901\u091a\u0924\u093e \u0939\u0948, \u092e\u094c\u091c\u0942\u0926 \u0928\u0939\u0940\u0902 \u0939\u0948\u0964"],["\u092e\u0941\u091d\u0947 \u0924\u0947\u091c\u093c \u0939\u094b\u0928\u0947 \u092a\u0930 \u0927\u094d\u092f\u093e\u0928 \u0926\u0947\u0928\u093e \u091a\u093e\u0939\u093f\u090f \u092f\u093e \u0917\u0932\u0924\u093f\u092f\u093e\u0901 \u0928 \u0915\u0930\u0928\u0947 \u092a\u0930?","\u0917\u0932\u0924\u093f\u092f\u093e\u0901 \u0928 \u0915\u0930\u0928\u0947 \u092a\u0930\u0964 \u0930\u092b\u093c\u094d\u0924\u093e\u0930 \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0947 \u0938\u093e\u0925 \u0905\u092a\u0928\u0947 \u0906\u092a \u0906 \u091c\u093e\u0924\u0940 \u0939\u0948, \u091c\u092c\u0915\u093f \u092f\u0939 \u0915\u0938\u0930\u0924 \u0905\u0938\u0932 \u092e\u0947\u0902 \u091c\u094b \u0915\u094c\u0936\u0932 \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u093f\u0924 \u0915\u0930\u0924\u0940 \u0939\u0948 \u0935\u0939 \u0939\u0948 no-go \u0938\u0902\u0915\u0947\u0924\u094b\u0902 \u092a\u0930 \u0915\u093f\u0938\u0940 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0915\u093e \u0938\u093e\u092b\u093c-\u0938\u0941\u0925\u0930\u093e \u0930\u0941\u0915\u093e\u0935\u0964"]],variants:"\u0907\u0938\u0915\u093e \u0915\u0930\u0940\u092c\u0940 \u0930\u093f\u0936\u094d\u0924\u0947\u0926\u093e\u0930 stop-signal \u0915\u093e\u0930\u094d\u092f \u0939\u0948, \u091c\u0939\u093e\u0901 \u0906\u092a \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0926\u0947\u0928\u093e \u0936\u0941\u0930\u0942 \u0915\u0930 \u091a\u0941\u0915\u0947 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902 \u0914\u0930 \u090f\u0915 \u0938\u0902\u0915\u0947\u0924 \u0906\u092a\u0915\u094b \u092c\u0940\u091a-\u0915\u094d\u0930\u093f\u092f\u093e \u092e\u0947\u0902 \u0930\u0941\u0915\u0928\u0947 \u0915\u094b \u0915\u0939\u0924\u093e \u0939\u0948, \u091c\u094b \u0925\u094b\u0921\u093c\u0947 \u0905\u0932\u0917 \u092c\u094d\u0930\u0947\u0915-\u0924\u0902\u0924\u094d\u0930 \u0915\u0940 \u091c\u093e\u0901\u091a \u0915\u0930\u0924\u093e \u0939\u0948\u0964 \u0926\u0942\u0938\u0930\u0947 \u0930\u0942\u092a \u0924\u091f\u0938\u094d\u0925 \u0938\u0902\u0915\u0947\u0924\u094b\u0902 \u0915\u0940 \u091c\u0917\u0939 \u092d\u093e\u0935\u0928\u093e\u0924\u094d\u092e\u0915 \u091a\u0947\u0939\u0930\u0947 \u092f\u093e \u0909\u091a\u094d\u091a-\u0915\u0948\u0932\u094b\u0930\u0940 \u092d\u094b\u091c\u0928 \u0924\u0925\u093e \u0936\u0930\u093e\u092c \u091c\u0948\u0938\u0940 \u0932\u0941\u092d\u093e\u0928\u0947 \u0935\u093e\u0932\u0940 \u091a\u0940\u091c\u093c\u0947\u0902 \u0930\u0916 \u0926\u0947\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u0915\u0908 \u0938\u0902\u0915\u0947\u0924\u094b\u0902 \u0915\u094b \u0924\u0947\u091c\u093c \u0915\u0930\u0915\u0947 \u092f\u093e \u0935\u093f\u0930\u0932 no-go \u0915\u094b \u0914\u0930 \u092d\u0940 \u0935\u093f\u0930\u0932 \u092c\u0928\u093e\u0915\u0930 \u0915\u0920\u093f\u0928\u093e\u0908 \u091c\u094b\u0921\u093c \u0926\u0947\u0924\u0947 \u0939\u0948\u0902\u0964"},zh:{about:"\u300c\u6291\u5236\u300d\u662f\u4e00\u9879 go/no-go\uff08\u53bb/\u4e0d\u53bb\uff09\u7ec3\u4e60\u3002\u4e00\u8fde\u4e32\u7ebf\u7d22\u9010\u4e2a\u95ea\u73b0\uff0c\u4f60\u7684\u4efb\u52a1\u662f\u5bf9\u300c\u53bb\u300d\u7ebf\u7d22\u5feb\u901f\u4f5c\u51fa\u53cd\u5e94\uff08\u901a\u5e38\u662f\u70b9\u51fb\uff09\uff0c\u800c\u5bf9\u300c\u4e0d\u53bb\u300d\u7ebf\u7d22\u5219\u8981\u5b8c\u5168\u6309\u4f4f\u3001\u4e0d\u52a8\u3002\u7531\u4e8e\u5927\u591a\u6570\u7ebf\u7d22\u90fd\u662f\u300c\u53bb\u300d\uff0c\u70b9\u51fb\u5c31\u53d8\u6210\u4e86\u4e00\u79cd\u53cd\u5c04\uff0c\u96be\u70b9\u5c31\u5728\u4e8e\uff1a\u5728\u90a3\u4e2a\u7f55\u89c1\u7684\u300c\u4e0d\u53bb\u300d\u7ebf\u7d22\u4e0a\uff0c\u8981\u8d76\u5728\u81ea\u5df1\u70b9\u4e0b\u53bb\u4e4b\u524d\u628a\u624b\u62fd\u4f4f\u3002",benefit:"\u5b83\u8bad\u7ec3\u53cd\u5e94\u6291\u5236\u2014\u2014\u4e5f\u5c31\u662f\u6267\u884c\u63a7\u5236\u4e2d\u8ba9\u4f60\u80fd\u53eb\u505c\u4e00\u4e2a\u5df2\u7ecf\u5728\u8def\u4e0a\u7684\u52a8\u4f5c\u7684\u90a3\u90e8\u5206\u80fd\u529b\u3002\u5b83\u540c\u6837\u4f9d\u8d56\u6301\u7eed\u6027\u6ce8\u610f\uff0c\u56e0\u4e3a\u53ea\u8981\u8d70\u4e00\u6b21\u795e\uff0c\u4f60\u7684\u624b\u6307\u5c31\u4f1a\u81ea\u987e\u81ea\u5730\u6253\u4e0b\u53bb\u3002",history:"go/no-go \u8fd9\u79cd\u8bbe\u7f6e\u8131\u80ce\u4e8e\u5341\u4e5d\u4e16\u7eaa\u7684\u53cd\u5e94\u65f6\u7814\u7a76\uff0c\u5230\u4e86\u4e8c\u5341\u4e16\u7eaa\u6210\u4e86\u4e34\u5e8a\u795e\u7ecf\u5fc3\u7406\u5b66\u7684\u4e3b\u529b\u5de5\u5177\u2014\u2014\u5728\u90a3\u91cc\uff0c\u65e0\u6cd5\u6291\u5236\u53cd\u5e94\u88ab\u4e0e\u989d\u53f6\u529f\u80fd\u8054\u7cfb\u5728\u4e86\u4e00\u8d77\u3002\u6b64\u540e\uff0c\u5b83\u6269\u6563\u8fdb\u4e86\u8ba4\u77e5\u5fc3\u7406\u5b66\u3001\u513f\u7ae5\u53d1\u5c55\uff0c\u4ee5\u53ca\u66f4\u665a\u8fd1\u7684\u3001\u57fa\u4e8e\u5e94\u7528\u7684\u5927\u8111\u8bad\u7ec3\uff0c\u8fd8\u6709\u9488\u5bf9\u98df\u7269\u548c\u9152\u7cbe\u7684\u4e60\u60ef\u6539\u53d8\u7814\u7a76\u4e2d\u3002",creator:"\u5b83\u6ca1\u6709\u5355\u4e00\u7684\u53d1\u660e\u8005\u3002go/no-go \u65b9\u6cd5\u6e90\u81ea\u53cd\u5e94\u65f6\u4f20\u7edf\uff0c\u8fd9\u4e00\u4f20\u7edf\u901a\u5e38\u88ab\u8ffd\u6eaf\u5230\u5f17\u6717\u897f\u65af\u5e93\u65af\xb7\u5510\u5fb7\u65af\uff08Franciscus Donders\uff0c1868\u5e74\uff09\uff1b\u5b83\u662f\u5728\u6574\u4e2a\u4e8c\u5341\u4e16\u7eaa\u7531\u7814\u7a76\u51b2\u52a8\u63a7\u5236\u548c\u989d\u53f6\u7684\u795e\u7ecf\u5fc3\u7406\u5b66\u5bb6\u4eec\u5171\u540c\u5851\u9020\u7684\uff0c\u800c\u975e\u51fa\u81ea\u67d0\u4e00\u4f4d\u5177\u540d\u7684\u4f5c\u8005\u3002",methods:"\u8ba9\u4f60\u7684\u624b\u6307\u653e\u677e\u3001\u5f85\u547d\uff0c\u800c\u4e0d\u8981\u7ef7\u7d27\u7740\u968f\u65f6\u51c6\u5907\u7838\u4e0b\u53bb\uff0c\u56e0\u4e3a\u6574\u4ef6\u4e8b\u7684\u5173\u952e\u5c31\u5728\u4e8e\u80fd\u591f\u4e2d\u6b62\u3002\u8981\u62b5\u4f4f\u4e0d\u60dc\u4e00\u5207\u53bb\u8ffd\u901f\u5ea6\u7684\u51b2\u52a8\uff0c\u56e0\u4e3a\u8fd9\u91cc\u771f\u6b63\u8981\u547d\u7684\u9519\u8bef\u662f\u5728\u300c\u4e0d\u53bb\u300d\u7ebf\u7d22\u4e0a\u70b9\u4e86\u4e0b\u53bb\uff0c\u800c\u4e0d\u662f\u6162\u4e0a\u90a3\u4e48\u4e00\u4e01\u70b9\u3002\u968f\u7740\u4f60\u7684\u8fdb\u6b65\uff0c\u628a\u8282\u594f\u52a0\u5feb\uff0c\u6216\u628a\u300c\u4e0d\u53bb\u300d\u7ebf\u7d22\u7684\u6bd4\u4f8b\u964d\u4f4e\uff0c\u597d\u8ba9\u300c\u505c\u4e0b\u300d\u59cb\u7ec8\u4fdd\u6301\u771f\u6b63\u7684\u96be\u5ea6\u3002",duration:"\u77ed\u800c\u9891\u7e41\u80dc\u8fc7\u957f\u800c\u7a00\u758f\u3002\u6bcf\u6b21\u4e94\u5230\u5341\u5206\u949f\u3001\u6bcf\u5468\u7ec3\u51e0\u6b21\uff0c\u5c31\u7ef0\u7ef0\u6709\u4f59\uff1b\u800c\u5355\u4e2a\u56de\u5408\u5e94\u5f53\u4fdd\u6301\u5f97\u8db3\u591f\u77ed\uff0c\u8ba9\u4f60\u7684\u6ce8\u610f\u529b\u4e0d\u81f3\u4e8e\u677e\u57ae\uff0c\u56e0\u4e3a\u75b2\u60eb\u7684\u6ce8\u610f\u529b\u6b63\u662f\u8ba9\u300c\u4e0d\u53bb\u300d\u4ece\u773c\u76ae\u5e95\u4e0b\u6e9c\u8fc7\u53bb\u7684\u6839\u6e90\u3002",research:"\u8bc1\u636e\u624e\u5b9e\u7684\u662f\u90a3\u4e2a\u663e\u800c\u6613\u89c1\u7684\u7ed3\u8bba\uff1a\u7ec3\u4e60\u4e4b\u540e\uff0c\u4f60\u4f1a\u66f4\u64c5\u957f\u8fd9\u7c7b\u300c\u505c\u4e0b\u300d\u4efb\u52a1\uff0c\u8bef\u70b9\u4e5f\u4f1a\u66f4\u5c11\u3002\u81f3\u4e8e\u8bf4\u5b83\u80fd\u5e7f\u6cdb\u63d0\u5347\u65e5\u5e38\u81ea\u63a7\u3001\u6574\u4f53\u6291\u5236\u51b2\u52a8\u3001\u6216\u8ba9\u65e0\u5173\u7684\u601d\u7ef4\u53d8\u654f\u9510\uff0c\u8fd9\u7c7b\u8bf4\u6cd5\u5219\u8981\u8584\u5f31\u5f97\u591a\u3002Enge \u53ca\u5176\u540c\u4e8b\u4e00\u9879\u8457\u540d\u7684\u8bad\u7ec3\u7814\u7a76\uff082014\uff09\u53d1\u73b0\uff0c\u9664\u4e86\u53d7\u8bad\u4efb\u52a1\u672c\u8eab\u4e4b\u5916\u5e76\u65e0\u771f\u6b63\u7684\u8fc1\u79fb\uff1b\u800c2024\u5e74\u4e00\u9879\u4ee5\u513f\u7ae5\u4e3a\u5bf9\u8c61\u7684\u7814\u7a76\u62a5\u544a\u79f0\uff0c\u6709\u9488\u5bf9\u6027\u7684\u53cd\u5e94\u6291\u5236\u8bad\u7ec3\u5bf9\u4ed6\u4eec\u7684\u5927\u8111\u6216\u884c\u4e3a\u51e0\u4e4e\u6ca1\u6709\u6539\u53d8\u3002\u9488\u5bf9\u7279\u5b9a\u98df\u7269\u7684\u7248\u672c\u80fd\u5c0f\u5e45\u538b\u4f4e\u5bf9\u6240\u8bad\u7ec3\u98df\u7269\u7684\u6444\u5165\u91cf\u3001\u5e76\u5728\u77ed\u671f\u5185\u6709\u6240\u5e2e\u52a9\uff0c\u4f46\u6301\u4e45\u800c\u666e\u904d\u7684\u6548\u679c\u5c1a\u672a\u786e\u7acb\uff0c\u6240\u4ee5\u5bf9\u90a3\u4e9b\u5b8f\u5927\u7684\u627f\u8bfa\u8981\u4fdd\u6301\u8c28\u614e\u3002",rec:"\u53bb\u8ffd\u6c42\u5e72\u51c0\u5229\u843d\u7684\u300c\u505c\u300d\uff0c\u800c\u4e0d\u662f\u7eaf\u7cb9\u7684\u901f\u5ea6\u3002\u4e00\u6b21\u96f6\u8bef\u70b9\u3001\u8fd1\u4e4e\u5b8c\u7f8e\u7684\u4f5c\u7b54\uff0c\u80dc\u8fc7\u4e00\u6b21\u6ee1\u662f\u8bef\u70b9\u7684\u5feb\u901f\u4f5c\u7b54\u3002",faq:[["\u5076\u5c14\u5728\u300c\u4e0d\u53bb\u300d\u4e0a\u70b9\u4e86\u4e00\u4e0b\uff0c\u5f88\u7cdf\u7cd5\u5417\uff1f","\u5076\u5c14\u5931\u624b\u662f\u6b63\u5e38\u7684\uff0c\u751a\u81f3\u662f\u610f\u6599\u4e4b\u4e2d\u7684\uff0c\u56e0\u4e3a\u8fd9\u5957\u8bbe\u8ba1\u5c31\u662f\u8981\u8ba9\u70b9\u51fb\u6210\u4e3a\u4e60\u60ef\u3002\u8981\u7d27\u7684\u662f\u8d8b\u52bf\uff1a\u4e00\u6b21\u6b21\u7ec3\u4e60\u4e0b\u6765\uff0c\u8bef\u70b9\u8d8a\u6765\u8d8a\u5c11\uff0c\u5c31\u610f\u5473\u7740\u4f60\u7684\u300c\u505c\u4e0b\u300d\u80fd\u529b\u6b63\u5728\u53d8\u5f97\u66f4\u654f\u9510\u3002"],["\u8fd9\u4f1a\u8ba9\u6211\u5728\u73b0\u5b9e\u751f\u6d3b\u4e2d\u4e0d\u90a3\u4e48\u51b2\u52a8\u5417\uff1f","\u8001\u5b9e\u8bf4\uff0c\u5927\u6982\u4e0d\u4f1a\u6709\u5e7f\u6cdb\u7684\u6548\u679c\u3002\u4f60\u4f1a\u53ef\u9760\u5730\u66f4\u64c5\u957f\u8fd9\u9879\u4efb\u52a1\u672c\u8eab\uff0c\u4f46\u8981\u8bf4 go/no-go \u7ec3\u4e60\u80fd\u8fc1\u79fb\u5230\u65e5\u5e38\u81ea\u63a7\u6216\u6574\u4f53\u51b2\u52a8\u6027\u4e0a\uff0c\u76ee\u524d\u7f3a\u4e4f\u6709\u529b\u7684\u8bc1\u636e\u3002"],["\u6211\u8be5\u4e13\u6ce8\u4e8e\u53d8\u5f97\u66f4\u5feb\uff0c\u8fd8\u662f\u4e13\u6ce8\u4e8e\u4e0d\u72af\u9519\uff1f","\u4e13\u6ce8\u4e8e\u4e0d\u72af\u9519\u3002\u901f\u5ea6\u4f1a\u968f\u7740\u7ec3\u4e60\u81ea\u5df1\u8ddf\u4e0a\u6765\uff0c\u800c\u8fd9\u9879\u7ec3\u4e60\u771f\u6b63\u8bad\u7ec3\u7684\u6280\u80fd\uff0c\u662f\u5728\u300c\u4e0d\u53bb\u300d\u7ebf\u7d22\u4e0a\u5e72\u51c0\u5229\u843d\u5730\u6291\u5236\u4f4f\u53cd\u5e94\u3002"]],variants:"\u5b83\u7684\u8fd1\u4eb2\u662f\u505c\u6b62\u4fe1\u53f7\u4efb\u52a1\uff08stop-signal task\uff09\u2014\u2014\u5728\u90a3\u91cc\uff0c\u4f60\u5df2\u7ecf\u5f00\u59cb\u4f5c\u51fa\u53cd\u5e94\uff0c\u4e00\u4e2a\u4fe1\u53f7\u544a\u8bc9\u4f60\u8981\u5728\u52a8\u4f5c\u8fdb\u884c\u5230\u4e00\u534a\u65f6\u4e2d\u6b62\u5b83\uff0c\u8fd9\u8003\u9a8c\u7684\u662f\u4e00\u79cd\u7565\u6709\u4e0d\u540c\u7684\u300c\u5239\u8f66\u300d\u673a\u5236\u3002\u5176\u4ed6\u53d8\u4f53\u4f1a\u628a\u4e2d\u6027\u7ebf\u7d22\u6362\u6210\u60c5\u7eea\u5316\u7684\u9762\u5b54\uff0c\u6216\u6362\u6210\u9ad8\u70ed\u91cf\u98df\u7269\u3001\u9152\u7cbe\u8fd9\u7c7b\u8bf1\u4eba\u7684\u4e1c\u897f\uff1b\u8bb8\u591a\u53d8\u4f53\u8fd8\u4f1a\u901a\u8fc7\u52a0\u5feb\u7ebf\u7d22\u901f\u5ea6\u3001\u6216\u8ba9\u90a3\u4e2a\u7f55\u89c1\u7684\u300c\u4e0d\u53bb\u300d\u53d8\u5f97\u66f4\u7f55\u89c1\u6765\u589e\u52a0\u96be\u5ea6\u3002"}},iowa:{ru:{about:"\xabIowa: 4 \u043a\u043e\u043b\u043e\u0434\u044b\xbb \u2014 \u043a\u0430\u0440\u0442\u043e\u0447\u043d\u0430\u044f \u0438\u0433\u0440\u0430 \u043d\u0430 \u0440\u0438\u0441\u043a \u0441 \u0447\u0435\u0442\u044b\u0440\u044c\u043c\u044f \u043a\u043e\u043b\u043e\u0434\u0430\u043c\u0438 \u0440\u0443\u0431\u0430\u0448\u043a\u043e\u0439 \u0432\u0432\u0435\u0440\u0445. \u041a\u0430\u0436\u0434\u044b\u0439 \u0445\u043e\u0434 \u0432\u044b \u0431\u0435\u0440\u0451\u0442\u0435 \u043a\u0430\u0440\u0442\u0443 \u0438\u0437 \u043b\u044e\u0431\u043e\u0439 \u043a\u043e\u043b\u043e\u0434\u044b, \u043f\u043e\u043b\u0443\u0447\u0430\u0435\u0442\u0435 \u043d\u0435\u043c\u043d\u043e\u0433\u043e \u0438\u0433\u0440\u043e\u0432\u044b\u0445 \u0434\u0435\u043d\u0435\u0433, \u0430 \u0438\u043d\u043e\u0433\u0434\u0430 \u0442\u0435\u0440\u044f\u0435\u0442\u0435 \u043a\u0440\u0443\u043f\u043d\u0443\u044e \u0441\u0443\u043c\u043c\u0443. \u0414\u0432\u0435 \u043a\u043e\u043b\u043e\u0434\u044b \u0441\u043e\u0431\u043b\u0430\u0437\u043d\u044f\u044e\u0442 \u0431\u043e\u043b\u044c\u0448\u0438\u043c\u0438 \u0432\u044b\u043f\u043b\u0430\u0442\u0430\u043c\u0438, \u043d\u043e \u0432 \u0438\u0442\u043e\u0433\u0435 \u043e\u0442\u043d\u0438\u043c\u0430\u044e\u0442 \u0435\u0449\u0451 \u0431\u043e\u043b\u044c\u0448\u0435; \u0434\u0432\u0435 \u0434\u0440\u0443\u0433\u0438\u0435 \u043f\u043b\u0430\u0442\u044f\u0442 \u043c\u0435\u043d\u044c\u0448\u0435 \u0437\u0430 \u043a\u0430\u0440\u0442\u0443, \u0437\u0430\u0442\u043e \u043e\u0441\u0442\u0430\u044e\u0442\u0441\u044f \u043f\u0440\u0438\u0431\u044b\u043b\u044c\u043d\u044b\u043c\u0438 \u0432\u0434\u043e\u043b\u0433\u0443\u044e. \u0417\u0430\u0434\u0430\u0447\u0430 \u2014 \u043d\u0430\u0449\u0443\u043f\u0430\u0442\u044c, \u043a\u0430\u043a\u0438\u0435 \u043a\u043e\u043b\u043e\u0434\u044b \u043d\u0430 \u0441\u0430\u043c\u043e\u043c \u0434\u0435\u043b\u0435 \u0432\u044b\u0433\u043e\u0434\u043d\u044b, \u0438 \u0434\u0435\u0440\u0436\u0430\u0442\u044c\u0441\u044f \u0437\u0430 \u043d\u0438\u0445.",benefit:"\u0422\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u043f\u0440\u0438\u043d\u044f\u0442\u0438\u0435 \u0440\u0435\u0448\u0435\u043d\u0438\u0439 \u0432 \u0443\u0441\u043b\u043e\u0432\u0438\u044f\u0445 \u043d\u0435\u043e\u043f\u0440\u0435\u0434\u0435\u043b\u0451\u043d\u043d\u043e\u0441\u0442\u0438: \u0443\u043c\u0435\u043d\u0438\u0435 \u0432\u0437\u0432\u0435\u0448\u0438\u0432\u0430\u0442\u044c \u0441\u0438\u044e\u043c\u0438\u043d\u0443\u0442\u043d\u0443\u044e \u0432\u044b\u0433\u043e\u0434\u0443 \u043f\u0440\u043e\u0442\u0438\u0432 \u043e\u0442\u043b\u043e\u0436\u0435\u043d\u043d\u043e\u0433\u043e \u043d\u0430\u043a\u0430\u0437\u0430\u043d\u0438\u044f, \u0443\u0447\u0438\u0442\u044c\u0441\u044f \u043d\u0430 \u043e\u0431\u0440\u0430\u0442\u043d\u043e\u0439 \u0441\u0432\u044f\u0437\u0438 \u0438 \u043d\u0435 \u0432\u0435\u0441\u0442\u0438\u0441\u044c \u043d\u0430 \u044f\u0440\u043a\u0438\u0439 \u043a\u0440\u0430\u0442\u043a\u043e\u0441\u0440\u043e\u0447\u043d\u044b\u0439 \u0432\u044b\u0438\u0433\u0440\u044b\u0448 \u0440\u0430\u0434\u0438 \u0431\u043e\u043b\u0435\u0435 \u0443\u0441\u0442\u043e\u0439\u0447\u0438\u0432\u043e\u0439 \u0441\u0442\u0430\u0432\u043a\u0438 \u0432\u0434\u043e\u043b\u0433\u0443\u044e.",history:"\u0418\u0433\u0440\u0430 \u043f\u0440\u0438\u0448\u043b\u0430 \u043f\u0440\u044f\u043c\u0438\u043a\u043e\u043c \u0438\u0437 \u043a\u043b\u0438\u043d\u0438\u0447\u0435\u0441\u043a\u043e\u0439 \u043d\u0435\u0439\u0440\u043e\u043d\u0430\u0443\u043a\u0438. \u0412 1994 \u0433\u043e\u0434\u0443 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u0438 \u0438\u0437 \u0423\u043d\u0438\u0432\u0435\u0440\u0441\u0438\u0442\u0435\u0442\u0430 \u0410\u0439\u043e\u0432\u044b \u043f\u0440\u0438\u0434\u0443\u043c\u0430\u043b\u0438 \u0435\u0451, \u0447\u0442\u043e\u0431\u044b \u043f\u043e\u043d\u044f\u0442\u044c, \u043f\u043e\u0447\u0435\u043c\u0443 \u043f\u0430\u0446\u0438\u0435\u043d\u0442\u044b \u0441 \u043f\u043e\u0432\u0440\u0435\u0436\u0434\u0435\u043d\u0438\u0435\u043c \u0432\u0435\u043d\u0442\u0440\u043e\u043c\u0435\u0434\u0438\u0430\u043b\u044c\u043d\u043e\u0439 \u043f\u0440\u0435\u0444\u0440\u043e\u043d\u0442\u0430\u043b\u044c\u043d\u043e\u0439 \u043a\u043e\u0440\u044b \u0440\u0430\u0437 \u0437\u0430 \u0440\u0430\u0437\u043e\u043c \u043f\u0440\u0438\u043d\u0438\u043c\u0430\u044e\u0442 \u0440\u0430\u0437\u0440\u0443\u0448\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0435 \u0436\u0438\u0437\u043d\u0435\u043d\u043d\u044b\u0435 \u0440\u0435\u0448\u0435\u043d\u0438\u044f \u043f\u0440\u0438 \u043d\u043e\u0440\u043c\u0430\u043b\u044c\u043d\u043e\u043c \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442\u0435. \u0421\u043e \u0432\u0440\u0435\u043c\u0435\u043d\u0435\u043c \u043e\u043d\u0430 \u0441\u0442\u0430\u043b\u0430 \u043e\u0434\u043d\u043e\u0439 \u0438\u0437 \u0441\u0430\u043c\u044b\u0445 \u0446\u0438\u0442\u0438\u0440\u0443\u0435\u043c\u044b\u0445 \u043c\u0435\u0442\u043e\u0434\u0438\u043a \u0438\u0437\u0443\u0447\u0435\u043d\u0438\u044f \u0432\u044b\u0431\u043e\u0440\u0430 \u2014 \u0432 \u0440\u0430\u0431\u043e\u0442\u0430\u0445 \u043f\u0440\u043e \u0437\u0430\u0432\u0438\u0441\u0438\u043c\u043e\u0441\u0442\u0438, \u0430\u0437\u0430\u0440\u0442 \u0438 \u0438\u043c\u043f\u0443\u043b\u044c\u0441\u0438\u0432\u043d\u043e\u0441\u0442\u044c.",creator:"\u0421\u043e\u0437\u0434\u0430\u043d\u0430 \u0432 1994 \u0433\u043e\u0434\u0443 \u0410\u043d\u0442\u0443\u0430\u043d\u043e\u043c \u0411\u0435\u0448\u0430\u0440\u043e\u0439 \u0432\u043c\u0435\u0441\u0442\u0435 \u0441 \u0410\u043d\u0442\u043e\u043d\u0438\u043e \u0414\u0430\u043c\u0430\u0441\u0438\u043e, \u0425\u0430\u043d\u043d\u043e\u0439 \u0414\u0430\u043c\u0430\u0441\u0438\u043e \u0438 \u0421\u0442\u0438\u0432\u0435\u043d\u043e\u043c \u0410\u043d\u0434\u0435\u0440\u0441\u043e\u043d\u043e\u043c \u0432 \u0423\u043d\u0438\u0432\u0435\u0440\u0441\u0438\u0442\u0435\u0442\u0435 \u0410\u0439\u043e\u0432\u044b \u2014 \u043e\u0442\u0441\u044e\u0434\u0430 \u0438 \u043d\u0430\u0437\u0432\u0430\u043d\u0438\u0435. \u0417\u0430\u0434\u0443\u043c\u044b\u0432\u0430\u043b\u0430\u0441\u044c \u043a\u0430\u043a \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u044c\u0441\u043a\u0438\u0439 \u0438 \u043a\u043b\u0438\u043d\u0438\u0447\u0435\u0441\u043a\u0438\u0439 \u0438\u043d\u0441\u0442\u0440\u0443\u043c\u0435\u043d\u0442, \u0430 \u043d\u0435 \u043a\u0430\u043a \u0438\u0433\u0440\u0430 \u0434\u043b\u044f \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0438 \u043c\u043e\u0437\u0433\u0430.",methods:"\u041f\u0435\u0440\u0432\u044b\u0435 \u043a\u0430\u0440\u0442\u044b \u0432\u043e\u0441\u043f\u0440\u0438\u043d\u0438\u043c\u0430\u0439\u0442\u0435 \u043a\u0430\u043a \u0440\u0430\u0437\u0432\u0435\u0434\u043a\u0443 \u0438 \u0441\u043c\u0438\u0440\u0438\u0442\u0435\u0441\u044c \u0441 \u043d\u0435\u0431\u043e\u043b\u044c\u0448\u0438\u043c\u0438 \u043f\u043e\u0442\u0435\u0440\u044f\u043c\u0438, \u043f\u043e\u043a\u0430 \u0441\u043e\u0441\u0442\u0430\u0432\u043b\u044f\u0435\u0442\u0435 \u043a\u0430\u0440\u0442\u0443 \u043a\u043e\u043b\u043e\u0434. \u0421\u043c\u043e\u0442\u0440\u0438\u0442\u0435 \u043d\u0430 \u0438\u0442\u043e\u0433 \u043f\u043e \u0441\u0435\u0440\u0438\u0438 \u043a\u0430\u0440\u0442, \u0430 \u043d\u0435 \u043d\u0430 \u043e\u0442\u0434\u0435\u043b\u044c\u043d\u044b\u0439 \u043a\u0443\u0448, \u0438 \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u0435\u0441\u044c \u0441 \u043f\u043e\u0434\u043e\u0437\u0440\u0435\u043d\u0438\u0435\u043c \u043a \u043a\u043e\u043b\u043e\u0434\u0435, \u043a\u043e\u0442\u043e\u0440\u0430\u044f \u043f\u043b\u0430\u0442\u0438\u0442 \u0449\u0435\u0434\u0440\u043e. \u0421\u043b\u0435\u0434\u0438\u0442\u0435 \u0438 \u0437\u0430 \u0440\u0438\u0442\u043c\u043e\u043c \u043f\u043e\u0442\u0435\u0440\u044c: \u043a\u043e\u043b\u043e\u0434\u0430, \u0433\u0434\u0435 \u043d\u0430\u043a\u0430\u0437\u0430\u043d\u0438\u044f \u0440\u0435\u0434\u043a\u0438\u0435, \u043d\u043e \u043e\u0433\u0440\u043e\u043c\u043d\u044b\u0435, \u0441\u043f\u043e\u0441\u043e\u0431\u043d\u0430 \u0442\u0438\u0445\u043e \u0432\u0430\u0441 \u043e\u0431\u0435\u0441\u043a\u0440\u043e\u0432\u0438\u0442\u044c, \u0442\u0430\u043a \u0447\u0442\u043e \u043d\u0435 \u0434\u0430\u0432\u0430\u0439\u0442\u0435 \u0440\u0435\u0434\u043a\u043e\u0439 \u0431\u043e\u043b\u0438 \u0443\u0431\u0435\u0434\u0438\u0442\u044c \u0441\u0435\u0431\u044f, \u0431\u0443\u0434\u0442\u043e \u0432\u0441\u0451 \u0431\u0435\u0437\u043e\u043f\u0430\u0441\u043d\u043e.",duration:"\u041f\u0430\u0440\u0442\u0438\u0438 \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u0435 \u043f\u043e \u0441\u0432\u043e\u0435\u0439 \u043f\u0440\u0438\u0440\u043e\u0434\u0435 \u2014 \u043e\u043a\u043e\u043b\u043e \u0441\u043e\u0442\u043d\u0438 \u0432\u044b\u0431\u043e\u0440\u043e\u0432 \u043a\u0430\u0440\u0442\u044b, \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u043c\u0438\u043d\u0443\u0442. \u041d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u0438\u0445 \u0437\u0430\u0445\u043e\u0434\u043e\u0432, \u0440\u0430\u0437\u043d\u0435\u0441\u0451\u043d\u043d\u044b\u0445 \u043f\u043e \u0434\u043d\u044f\u043c, \u0434\u043e\u0441\u0442\u0430\u0442\u043e\u0447\u043d\u043e, \u0447\u0442\u043e\u0431\u044b \u0441\u0442\u0440\u0430\u0442\u0435\u0433\u0438\u044f \u043e\u0442\u0442\u043e\u0447\u0438\u043b\u0430\u0441\u044c; \u0441\u0438\u0434\u0435\u0442\u044c \u043d\u0430\u0434 \u0438\u0433\u0440\u043e\u0439 \u0447\u0430\u0441\u0430\u043c\u0438 \u043f\u043e\u0434\u0440\u044f\u0434 \u0441\u043c\u044b\u0441\u043b\u0430 \u043c\u0430\u043b\u043e.",research:"\u0422\u0432\u0451\u0440\u0434\u043e \u0434\u043e\u043a\u0430\u0437\u0430\u043d\u043e \u043d\u0435\u043c\u043d\u043e\u0433\u043e\u0435: \u0447\u0435\u043b\u043e\u0432\u0435\u043a \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043b\u044c\u043d\u043e \u043d\u0430\u0447\u0438\u043d\u0430\u0435\u0442 \u0438\u0433\u0440\u0430\u0442\u044c \u043b\u0443\u0447\u0448\u0435 \u0438\u043c\u0435\u043d\u043d\u043e \u0432 \u044d\u0442\u043e\u0439 \u0437\u0430\u0434\u0430\u0447\u0435, \u043f\u043e \u043c\u0435\u0440\u0435 \u0442\u043e\u0433\u043e \u043a\u0430\u043a \u0445\u043e\u0440\u043e\u0448\u0438\u0435 \u0438 \u043f\u043b\u043e\u0445\u0438\u0435 \u043a\u043e\u043b\u043e\u0434\u044b \u0440\u0430\u0441\u043a\u0440\u044b\u0432\u0430\u044e\u0442\u0441\u044f \u0447\u0435\u0440\u0435\u0437 \u043e\u0431\u0440\u0430\u0442\u043d\u0443\u044e \u0441\u0432\u044f\u0437\u044c, \u0430 \u043a\u043b\u0438\u043d\u0438\u0447\u0435\u0441\u043a\u0438\u0435 \u0433\u0440\u0443\u043f\u043f\u044b \u0441\u0442\u0430\u0431\u0438\u043b\u044c\u043d\u043e \u0432\u044b\u0431\u0438\u0440\u0430\u044e\u0442 \u0445\u0443\u0436\u0435 \u0437\u0434\u043e\u0440\u043e\u0432\u044b\u0445 \u2014 \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u043c\u0435\u0442\u043e\u0434\u0438\u043a\u0430 \u0438 \u043e\u0441\u0442\u0430\u0451\u0442\u0441\u044f \u043f\u043e\u043b\u0435\u0437\u043d\u043e\u0439 \u0434\u043b\u044f \u043e\u0446\u0435\u043d\u043a\u0438. \u0417\u043d\u0430\u043c\u0435\u043d\u0438\u0442\u043e\u0435 \u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043d\u0438\u0435, \u0431\u0443\u0434\u0442\u043e \u043b\u044e\u0434\u0438 \u0440\u0435\u0448\u0430\u044e\u0442 \u0432\u0435\u0440\u043d\u043e \xab\u0435\u0449\u0451 \u043d\u0435 \u043f\u043e\u043d\u0438\u043c\u0430\u044f\xbb \u0441\u0442\u0440\u0430\u0442\u0435\u0433\u0438\u0438, \u043d\u0430 \u0438\u043d\u0442\u0443\u0438\u0442\u0438\u0432\u043d\u044b\u0445 \u0442\u0435\u043b\u0435\u0441\u043d\u044b\u0445 \u0441\u0438\u0433\u043d\u0430\u043b\u0430\u0445, \u043e\u0441\u043f\u0430\u0440\u0438\u0432\u0430\u0435\u0442\u0441\u044f. \u041c\u0430\u0439\u044f \u0438 \u041c\u0430\u043a\u043a\u043b\u0435\u043b\u043b\u0430\u043d\u0434 (2004) \u043f\u043e\u043a\u0430\u0437\u0430\u043b\u0438, \u0447\u0442\u043e \u0443\u0447\u0430\u0441\u0442\u043d\u0438\u043a\u0438 \u043e\u0431\u044b\u0447\u043d\u043e \u0432\u0441\u0451 \u0436\u0435 \u043e\u0441\u043e\u0437\u043d\u0430\u044e\u0442 \u043b\u043e\u0433\u0438\u043a\u0443, \u0430 \u0432\u043e \u043c\u043d\u043e\u0433\u0438\u0445 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u044f\u0445 \u0437\u0434\u043e\u0440\u043e\u0432\u044b\u0435 \u043b\u044e\u0434\u0438 \u043f\u0440\u0435\u0434\u043f\u043e\u0447\u0438\u0442\u0430\u044e\u0442 \u043a\u043e\u043b\u043e\u0434\u0443 \u0441 \u0440\u0435\u0434\u043a\u0438\u043c\u0438 \u043f\u043e\u0442\u0435\u0440\u044f\u043c\u0438, \u0445\u043e\u0442\u044f \u0432\u0434\u043e\u043b\u0433\u0443\u044e \u043e\u043d\u0430 \u0443\u0431\u044b\u0442\u043e\u0447\u043d\u0430. \u0422\u0430\u043a \u0447\u0442\u043e \u0433\u043b\u0443\u0431\u043e\u043a\u0430\u044f \u0442\u0440\u0430\u043a\u0442\u043e\u0432\u043a\u0430 \u0447\u0435\u0440\u0435\u0437 \xab\u0441\u043e\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u0438\u0435 \u043c\u0430\u0440\u043a\u0435\u0440\u044b\xbb \u0434\u0430\u043b\u0435\u043a\u043e \u043d\u0435 \u0437\u0430\u043a\u0440\u044b\u0442\u0430, \u0438 \u043d\u0435\u0442 \u0443\u0431\u0435\u0434\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0445 \u0434\u0430\u043d\u043d\u044b\u0445, \u0447\u0442\u043e \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0430 \u0434\u0435\u043b\u0430\u0435\u0442 \u0432\u0430\u0441 \u0431\u043e\u043b\u0435\u0435 \u043c\u0443\u0434\u0440\u044b\u043c \u0432 \u0440\u0435\u0430\u043b\u044c\u043d\u044b\u0445 \u0440\u0435\u0448\u0435\u043d\u0438\u044f\u0445.",rec:"\u041d\u0435 \u043e\u0431\u0440\u0430\u0449\u0430\u0439\u0442\u0435 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f \u043d\u0430 \u0432\u0435\u043b\u0438\u0447\u0438\u043d\u0443 \u043e\u0442\u0434\u0435\u043b\u044c\u043d\u043e\u0433\u043e \u0432\u044b\u0438\u0433\u0440\u044b\u0448\u0430 \u2014 \u043e\u0446\u0435\u043d\u0438\u0432\u0430\u0439\u0442\u0435 \u043a\u043e\u043b\u043e\u0434\u0443 \u0442\u043e\u043b\u044c\u043a\u043e \u043f\u043e \u0442\u043e\u043c\u0443, \u0433\u0434\u0435 \u043e\u043a\u0430\u0437\u044b\u0432\u0430\u0435\u0442\u0441\u044f \u0432\u0430\u0448 \u0431\u0430\u043b\u0430\u043d\u0441 \u043f\u043e\u0441\u043b\u0435 \u043c\u043d\u043e\u0433\u0438\u0445 \u043a\u0430\u0440\u0442.",faq:[["\u0415\u0441\u0442\u044c \u043a\u043e\u043b\u043e\u0434\u0430, \u043a\u043e\u0442\u043e\u0440\u0443\u044e \u0432\u0441\u0435\u0433\u0434\u0430 \u0441\u0442\u043e\u0438\u0442 \u0432\u044b\u0431\u0438\u0440\u0430\u0442\u044c?","\u041e\u0434\u043d\u043e\u0437\u043d\u0430\u0447\u043d\u043e\u0433\u043e \u043e\u0442\u0432\u0435\u0442\u0430 \u043d\u0435\u0442: \u043a\u043e\u043b\u043e\u0434\u044b \u043e\u043f\u0440\u0435\u0434\u0435\u043b\u044f\u044e\u0442\u0441\u044f \u0441\u0445\u0435\u043c\u043e\u0439 \u0432\u044b\u043f\u043b\u0430\u0442, \u0430 \u043d\u0435 \u043c\u0435\u0441\u0442\u043e\u043c \u043d\u0430 \u0441\u0442\u043e\u043b\u0435. \u0414\u0432\u0435 \u0432\u044b\u0433\u043e\u0434\u043d\u044b \u043d\u0430 \u0434\u043b\u0438\u043d\u043d\u043e\u0439 \u0434\u0438\u0441\u0442\u0430\u043d\u0446\u0438\u0438, \u0434\u0432\u0435 \u2014 \u043d\u0435\u0442; \u0432\u0430\u0448\u0430 \u0437\u0430\u0434\u0430\u0447\u0430 \u0432 \u043a\u0430\u0436\u0434\u043e\u0439 \u043f\u0430\u0440\u0442\u0438\u0438 \u2014 \u043f\u043e \u0432\u044b\u0438\u0433\u0440\u044b\u0448\u0430\u043c \u0438 \u043f\u043e\u0442\u0435\u0440\u044f\u043c \u043f\u043e\u043d\u044f\u0442\u044c, \u043a\u0430\u043a\u0438\u0435 \u0438\u043c\u0435\u043d\u043d\u043e \u0445\u043e\u0440\u043e\u0448\u0438\u0435, \u0438 \u0434\u0435\u0440\u0436\u0430\u0442\u044c\u0441\u044f \u0437\u0430 \u043d\u0438\u0445."],["\u042f \u0432\u0441\u0451 \u0432\u0440\u0435\u043c\u044f \u0442\u044f\u043d\u0443\u0441\u044c \u043a \u043a\u043e\u043b\u043e\u0434\u0435 \u0441 \u0440\u0435\u0434\u043a\u0438\u043c, \u043d\u043e \u043a\u0440\u0443\u043f\u043d\u044b\u043c \u043f\u0440\u043e\u0438\u0433\u0440\u044b\u0448\u0435\u043c. \u042d\u0442\u043e \u043e\u0448\u0438\u0431\u043a\u0430?","\u0412\u044b \u043f\u043e\u043f\u0430\u043b\u0438\u0441\u044c \u0432 \u0445\u043e\u0440\u043e\u0448\u043e \u0438\u0437\u0432\u0435\u0441\u0442\u043d\u0443\u044e \u043b\u043e\u0432\u0443\u0448\u043a\u0443. \u041a\u043e\u043b\u043e\u0434\u0430, \u0447\u0442\u043e \u043d\u0430\u043a\u0430\u0437\u044b\u0432\u0430\u0435\u0442 \u043b\u0438\u0448\u044c \u0438\u0437\u0440\u0435\u0434\u043a\u0430, \u043a\u0430\u0436\u0435\u0442\u0441\u044f \u0431\u0435\u0437\u043e\u043f\u0430\u0441\u043d\u043e\u0439, \u043d\u043e \u043e\u0434\u0438\u043d \u0435\u0451 \u043f\u0440\u043e\u0438\u0433\u0440\u044b\u0448 \u0441\u043f\u043e\u0441\u043e\u0431\u0435\u043d \u043f\u0435\u0440\u0435\u043a\u0440\u044b\u0442\u044c \u0432\u0441\u0435 \u0432\u044b\u0438\u0433\u0440\u044b\u0448\u0438. \u0421\u043b\u0435\u0434\u0438\u0442\u0435 \u0437\u0430 \u043e\u0431\u0449\u0438\u043c \u0441\u0447\u0451\u0442\u043e\u043c, \u0430 \u043d\u0435 \u0437\u0430 \u0442\u0435\u043c, \u043a\u0430\u043a \u0447\u0430\u0441\u0442\u043e \u043a\u043e\u043b\u043e\u0434\u0430 \u0436\u0430\u043b\u0438\u0442."],["\u0421\u0442\u0430\u043d\u0443\u0442 \u043b\u0438 \u043c\u043e\u0438 \u0440\u0435\u0430\u043b\u044c\u043d\u044b\u0435 \u0440\u0435\u0448\u0435\u043d\u0438\u044f \u043e \u0434\u0435\u043d\u044c\u0433\u0430\u0445 \u0438 \u0436\u0438\u0437\u043d\u0438 \u043b\u0443\u0447\u0448\u0435 \u043e\u0442 \u044d\u0442\u043e\u0439 \u0438\u0433\u0440\u044b?","\u0427\u0435\u0441\u0442\u043d\u043e \u2014 \u0443\u0431\u0435\u0434\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0445 \u0434\u0430\u043d\u043d\u044b\u0445 \u0437\u0430 \u044d\u0442\u043e \u043d\u0435\u0442. \u0412\u044b \u043d\u0430\u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442\u0435\u0441\u044c \u0447\u0438\u0442\u0430\u0442\u044c \u044d\u0442\u0438 \u043a\u043e\u043b\u043e\u0434\u044b, \u043d\u043e \u043f\u0435\u0440\u0435\u043d\u043e\u0441 \u043d\u0430 \u0440\u0435\u0430\u043b\u044c\u043d\u044b\u0435 \u0444\u0438\u043d\u0430\u043d\u0441\u043e\u0432\u044b\u0435 \u0438 \u0436\u0438\u0437\u043d\u0435\u043d\u043d\u044b\u0435 \u0432\u044b\u0431\u043e\u0440\u044b \u043d\u0435 \u0434\u043e\u043a\u0430\u0437\u0430\u043d. \u0421\u0447\u0438\u0442\u0430\u0439\u0442\u0435 \u044d\u0442\u043e \u0443\u0437\u043a\u0438\u043c \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u0435\u043c \u043d\u0430 \u043c\u044b\u0448\u043b\u0435\u043d\u0438\u0435 \u0441 \u043e\u0442\u043b\u043e\u0436\u0435\u043d\u043d\u043e\u0439 \u043d\u0430\u0433\u0440\u0430\u0434\u043e\u0439, \u0430 \u043d\u0435 \u0430\u043f\u0433\u0440\u0435\u0439\u0434\u043e\u043c \u0436\u0438\u0437\u043d\u0438."]],variants:"\u0420\u0430\u0441\u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0451\u043d\u043d\u044b\u0435 \u0432\u0430\u0440\u0438\u0430\u0446\u0438\u0438 \u043c\u0435\u043d\u044f\u044e\u0442 \u0447\u0438\u0441\u043b\u043e \u043a\u043e\u043b\u043e\u0434, \u043f\u0435\u0440\u0435\u0441\u0442\u0430\u0432\u043b\u044f\u044e\u0442, \u043d\u0430\u043a\u0430\u0437\u044b\u0432\u0430\u044e\u0442 \u043b\u0438 \u043f\u043b\u043e\u0445\u0438\u0435 \u043a\u043e\u043b\u043e\u0434\u044b \u0447\u0430\u0441\u0442\u043e \u0438\u043b\u0438 \u0440\u0435\u0434\u043a\u043e, \u043f\u0435\u0440\u0435\u0432\u043e\u0440\u0430\u0447\u0438\u0432\u0430\u044e\u0442 \u0438\u0433\u0440\u0443 \u0432 \u0432\u0435\u0440\u0441\u0438\u044e \xab\u0441\u043d\u0430\u0447\u0430\u043b\u0430 \u043c\u0438\u043d\u0443\u0441\xbb, \u0433\u0434\u0435 \u0432\u044b \u0441\u0442\u0430\u0440\u0442\u0443\u0435\u0442\u0435 \u0432 \u0434\u043e\u043b\u0433\u0443, \u0443\u043a\u043e\u0440\u0430\u0447\u0438\u0432\u0430\u044e\u0442 \u0438\u043b\u0438 \u0443\u0434\u043b\u0438\u043d\u044f\u044e\u0442 \u0441\u0435\u0440\u0438\u044e, \u043b\u0438\u0431\u043e \u0434\u043e\u0431\u0430\u0432\u043b\u044f\u044e\u0442 \u0432\u043e\u043f\u0440\u043e\u0441 \u043e \u0432\u0430\u0448\u0435\u0439 \u0443\u0432\u0435\u0440\u0435\u043d\u043d\u043e\u0441\u0442\u0438 \u2014 \u0447\u0442\u043e\u0431\u044b \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u0438 \u043c\u043e\u0433\u043b\u0438 \u043f\u0440\u043e\u0432\u0435\u0440\u0438\u0442\u044c, \u0447\u0442\u043e \u0438\u043c\u0435\u043d\u043d\u043e \u0432\u044b \u043e\u0441\u043e\u0437\u043d\u0430\u0451\u0442\u0435."},en:{about:"Iowa: 4 Decks is a card-gambling task with four face-down decks. On every turn you pick a card from any deck, win some play money, and sometimes lose a chunk of it. Two decks tempt you with big payouts but hand back even bigger losses over time; the other two pay less per card but stay profitable in the long run, and your job is to feel out which decks are actually good and keep choosing them.",benefit:"It trains decision-making under uncertainty: weighing immediate reward against delayed punishment, learning from feedback, and overriding the pull of a flashy short-term win in favour of the steadier long-term bet.",history:"It comes straight from clinical neuroscience. Researchers at the University of Iowa built it in 1994 to explain why patients with damage to the ventromedial prefrontal cortex kept making ruinous real-life choices despite normal IQ, and it became one of the most cited decision-making tasks in psychology, used in studies of addiction, gambling, and impulsivity.",creator:"Created in 1994 by Antoine Bechara together with Antonio Damasio, Hanna Damasio, and Steven Anderson at the University of Iowa, which is where the name comes from. It was designed as a research and clinical instrument, not as a brain-training game.",methods:"Treat the early cards as pure reconnaissance and expect to lose a little while you map the decks. Pay attention to net result over a run of cards, not to any single jackpot, and be suspicious of a deck that pays big. Watch the rhythm of the losses too: a deck whose punishments are rare but huge can quietly bleed you, so don't let infrequent pain fool you into thinking it is safe.",duration:"Sessions are naturally short, on the order of a hundred card picks or a few minutes. A handful of runs spread across days is plenty to see your strategy sharpen; there is little point grinding it for hours in one sitting.",research:"What is solid is narrow: people, and you, get better at this specific task as the good and bad decks reveal themselves through feedback, and clinical groups reliably choose worse than healthy ones, which is why it stays useful as an assessment. The famous claim that people decide well 'before knowing' the strategy, driven by gut bodily signals, is contested. Maia and McClelland (2004) found participants usually do have conscious knowledge, and many studies report healthy people favouring the deck with rare losses even though it loses money long term, so the deeper somatic-marker story is far from settled, and there is no good evidence that drilling it makes you a wiser decision-maker in real life.",rec:"Ignore the size of any one win and judge each deck only by where it leaves your balance after many cards.",faq:[["Is there a deck I should just always pick?","No fixed answer, because the decks are defined by their payoff pattern, not their position. Two decks are profitable over many cards and two are not; your task each game is to discover which is which from the wins and losses, then stick with the good ones."],["I keep choosing the deck with the rare big loss. Am I doing it wrong?","You are falling for a well-documented trap. A deck that punishes you only occasionally feels safe, yet its single losses can outweigh all its wins. Track your running total rather than how often a deck stings you."],["Will playing this make me better at real-world money or life decisions?","Honestly, there's no good evidence for that. You will get better at reading these decks, but broad transfer to real financial or life choices is unproven. Treat it as a focused exercise in delayed-reward thinking, not a life upgrade."]],variants:"Common variations change the number of decks, swap whether the bad decks punish you often or rarely, flip it into a loss-first version where you start in debt, shorten or lengthen the run, or add a version that asks how confident you are so researchers can probe what you consciously know."},es:{about:"Iowa: 4 Mazos es una tarea de apuestas con cartas y cuatro mazos boca abajo. En cada turno eliges una carta de cualquier mazo, ganas algo de dinero ficticio y, a veces, pierdes una buena parte. Dos mazos te tientan con premios grandes pero, a la larga, te devuelven p\xe9rdidas a\xfan mayores; los otros dos pagan menos por carta pero siguen siendo rentables a largo plazo. Tu misi\xf3n es ir intuyendo qu\xe9 mazos son realmente buenos y seguir eligi\xe9ndolos.",benefit:"Entrena la toma de decisiones en condiciones de incertidumbre: sopesar la recompensa inmediata frente al castigo aplazado, aprender de la retroalimentaci\xf3n y resistir el tir\xf3n de una ganancia llamativa a corto plazo en favor de la apuesta m\xe1s estable a largo plazo.",history:"Viene directamente de la neurociencia cl\xednica. Unos investigadores de la Universidad de Iowa la dise\xf1aron en 1994 para explicar por qu\xe9 pacientes con da\xf1o en la corteza prefrontal ventromedial segu\xedan tomando decisiones ruinosas en la vida real pese a tener un cociente intelectual normal. Se convirti\xf3 en una de las tareas de toma de decisiones m\xe1s citadas de la psicolog\xeda, usada en estudios sobre adicci\xf3n, ludopat\xeda e impulsividad.",creator:"Creada en 1994 por Antoine Bechara junto con Antonio Damasio, Hanna Damasio y Steven Anderson en la Universidad de Iowa, de donde viene el nombre. Se dise\xf1\xf3 como instrumento de investigaci\xf3n y cl\xednico, no como un juego de entrenamiento mental.",methods:"Trata las primeras cartas como pura exploraci\xf3n y cuenta con perder un poco mientras vas trazando el mapa de los mazos. F\xedjate en el resultado neto a lo largo de una tanda de cartas, no en un \xfanico premio gordo, y desconf\xeda del mazo que paga mucho. Vigila tambi\xe9n el ritmo de las p\xe9rdidas: un mazo cuyos castigos son raros pero enormes puede desangrarte sin que te des cuenta, as\xed que no dejes que un dolor poco frecuente te haga creer que es seguro.",duration:"Las sesiones son cortas por naturaleza, del orden de un centenar de cartas o unos pocos minutos. Un pu\xf1ado de partidas repartidas a lo largo de varios d\xedas basta para ver c\xf3mo se afina tu estrategia; tiene poco sentido machacarlo durante horas de una sentada.",research:"Lo s\xf3lido es concreto: la gente, y t\xfa tambi\xe9n, mejora en esta tarea espec\xedfica a medida que los mazos buenos y malos se van revelando a trav\xe9s de la retroalimentaci\xf3n, y los grupos cl\xednicos eligen de forma fiable peor que los sanos, por eso sigue siendo \xfatil como evaluaci\xf3n. La famosa afirmaci\xf3n de que la gente decide bien 'antes de saber' la estrategia, guiada por se\xf1ales corporales viscerales, est\xe1 en discusi\xf3n. Maia y McClelland (2004) hallaron que los participantes suelen tener conocimiento consciente, y muchos estudios reportan que personas sanas prefieren el mazo de p\xe9rdidas raras aunque pierda dinero a largo plazo, as\xed que la hip\xf3tesis del marcador som\xe1tico dista de estar zanjada, y no hay buena evidencia de que practicarlo te haga tomar mejores decisiones en la vida real.",rec:"Ignora el tama\xf1o de cualquier ganancia individual y juzga cada mazo solo por d\xf3nde deja tu saldo despu\xe9s de muchas cartas.",faq:[["\xbfHay un mazo que deba elegir siempre?","No hay respuesta fija, porque los mazos se definen por su patr\xf3n de pagos, no por su posici\xf3n. Dos mazos son rentables a lo largo de muchas cartas y dos no lo son; tu tarea en cada partida es descubrir cu\xe1l es cu\xe1l a partir de las ganancias y p\xe9rdidas, y luego quedarte con los buenos."],["Sigo eligiendo el mazo de la p\xe9rdida rara pero grande. \xbfLo estoy haciendo mal?","Est\xe1s cayendo en una trampa bien documentada. Un mazo que solo te castiga de vez en cuando da sensaci\xf3n de seguridad, pero sus p\xe9rdidas aisladas pueden superar todas sus ganancias. Lleva la cuenta de tu total acumulado en lugar de fijarte en cu\xe1ntas veces te pincha un mazo."],["\xbfJugar a esto me har\xe1 tomar mejores decisiones con el dinero o en la vida real?","Sinceramente, no hay buena evidencia de ello. Mejorar\xe1s leyendo estos mazos, pero la transferencia amplia a decisiones financieras o vitales reales no est\xe1 demostrada. T\xf3malo como un ejercicio concreto de pensar en la recompensa aplazada, no como una mejora vital."]],variants:"Las variantes habituales cambian el n\xfamero de mazos, alternan si los mazos malos te castigan a menudo o rara vez, le dan la vuelta a una versi\xf3n que empieza en n\xfameros rojos donde arrancas endeudado, acortan o alargan la tanda, o a\xf1aden una versi\xf3n que te pregunta cu\xe1nta confianza tienes para que los investigadores puedan sondear lo que sabes conscientemente."},de:{about:"Iowa: 4 Decks ist eine Gl\xfccksspielaufgabe mit Karten und vier verdeckten Stapeln. In jedem Zug ziehst du eine Karte von einem beliebigen Stapel, gewinnst etwas Spielgeld und verlierst manchmal einen gr\xf6\xdferen Batzen davon. Zwei Stapel locken mit hohen Auszahlungen, kassieren \xfcber die Zeit aber noch h\xf6here Verluste; die anderen beiden zahlen pro Karte weniger, bleiben auf lange Sicht jedoch profitabel. Deine Aufgabe ist es herauszusp\xfcren, welche Stapel tats\xe4chlich gut sind, und konsequent bei ihnen zu bleiben.",benefit:"Sie schult das Entscheiden unter Unsicherheit: das Abw\xe4gen zwischen sofortiger Belohnung und verz\xf6gerter Bestrafung, das Lernen aus R\xfcckmeldung und das \xdcberwinden des Reizes eines auff\xe4lligen kurzfristigen Gewinns zugunsten der ruhigeren, langfristig besseren Wette.",history:"Sie stammt direkt aus der klinischen Neurowissenschaft. Forscher der University of Iowa entwickelten sie 1994, um zu erkl\xe4ren, warum Patienten mit Sch\xe4digung des ventromedialen pr\xe4frontalen Kortex trotz normalem IQ im echten Leben immer wieder ruin\xf6se Entscheidungen trafen. Sie wurde zu einer der meistzitierten Entscheidungsaufgaben der Psychologie und kam in Studien zu Sucht, Gl\xfccksspiel und Impulsivit\xe4t zum Einsatz.",creator:"Entwickelt 1994 von Antoine Bechara gemeinsam mit Antonio Damasio, Hanna Damasio und Steven Anderson an der University of Iowa, woher auch der Name stammt. Sie wurde als Forschungs- und klinisches Instrument konzipiert, nicht als Gehirntrainingsspiel.",methods:"Behandle die ersten Karten als reine Erkundung und rechne damit, ein wenig zu verlieren, w\xe4hrend du die Stapel kartierst. Achte auf das Nettoergebnis \xfcber eine Reihe von Karten hinweg, nicht auf einen einzelnen Jackpot, und sei misstrauisch gegen\xfcber einem Stapel, der gro\xdf auszahlt. Beobachte auch den Rhythmus der Verluste: Ein Stapel, dessen Strafen selten, aber gewaltig sind, kann dich unbemerkt ausbluten lassen \u2014 lass dich von seltenem Schmerz nicht zu der Annahme verleiten, er sei sicher.",duration:"Die Sitzungen sind von Natur aus kurz, in der Gr\xf6\xdfenordnung von etwa hundert Kartenz\xfcgen oder wenigen Minuten. Eine Handvoll Durchl\xe4ufe \xfcber mehrere Tage verteilt reicht v\xf6llig aus, um die eigene Strategie sch\xe4rfer werden zu sehen; stundenlanges Durchackern an einem St\xfcck bringt wenig.",research:"Belastbar ist nur das Enge: Menschen \u2014 und du \u2014 werden in genau dieser Aufgabe besser, sobald sich die guten und schlechten Stapel durch die R\xfcckmeldung offenbaren, und klinische Gruppen w\xe4hlen zuverl\xe4ssig schlechter als gesunde, weshalb sie als Diagnoseinstrument n\xfctzlich bleibt. Die ber\xfchmte Behauptung, Menschen entschieden gut, 'bevor sie die Strategie kennen', getrieben von k\xf6rperlichen Bauchgef\xfchlen, ist umstritten. Maia und McClelland (2004) fanden, dass Versuchspersonen meist sehr wohl bewusstes Wissen haben, und viele Studien berichten, dass gesunde Menschen den Stapel mit den seltenen Verlusten bevorzugen, obwohl er langfristig Geld verliert. Die tiefere Geschichte der somatischen Marker ist also l\xe4ngst nicht gekl\xe4rt, und es gibt keinen guten Beleg daf\xfcr, dass das \xdcben dich im echten Leben zu einem kl\xfcgeren Entscheider macht.",rec:"Ignoriere die H\xf6he jedes einzelnen Gewinns und beurteile jeden Stapel allein danach, wo er deinen Kontostand nach vielen Karten zur\xfcckl\xe4sst.",faq:[["Gibt es einen Stapel, den ich einfach immer ziehen sollte?","Keine feste Antwort, denn die Stapel sind durch ihr Auszahlungsmuster definiert, nicht durch ihre Position. Zwei Stapel sind \xfcber viele Karten profitabel und zwei nicht; deine Aufgabe ist es in jedem Spiel, aus Gewinnen und Verlusten herauszufinden, welche das sind, und dann bei den guten zu bleiben."],["Ich w\xe4hle st\xe4ndig den Stapel mit dem seltenen gro\xdfen Verlust. Mache ich es falsch?","Du tappst in eine gut dokumentierte Falle. Ein Stapel, der dich nur gelegentlich bestraft, f\xfchlt sich sicher an, doch seine einzelnen Verluste k\xf6nnen alle seine Gewinne aufwiegen. Verfolge deinen laufenden Gesamtstand, nicht, wie oft ein Stapel sticht."],["Werde ich dadurch besser bei echten Geld- oder Lebensentscheidungen?","Ehrlich gesagt gibt es daf\xfcr keinen guten Beleg. Du wirst besser darin, diese Stapel zu lesen, aber ein breiter \xdcbertrag auf echte finanzielle oder Lebensentscheidungen ist unbewiesen. Betrachte es als gezielte \xdcbung im Denken \xfcber verz\xf6gerte Belohnung, nicht als Lebens-Upgrade."]],variants:"\xdcbliche Abwandlungen ver\xe4ndern die Anzahl der Stapel, vertauschen, ob die schlechten Stapel h\xe4ufig oder selten bestrafen, kehren das Ganze in eine Verlust-zuerst-Variante um, in der du verschuldet startest, verk\xfcrzen oder verl\xe4ngern den Durchlauf oder erg\xe4nzen eine Version, die nach deiner Sicherheit fragt, damit Forscher pr\xfcfen k\xf6nnen, was du bewusst wei\xdft."},pt:{about:"Iowa: 4 Baralhos \xe9 uma tarefa de aposta com cartas, usando quatro baralhos virados para baixo. A cada rodada voc\xea escolhe uma carta de qualquer baralho, ganha um pouco de dinheiro de brincadeira e, \xe0s vezes, perde uma boa parte dele. Dois baralhos seduzem com pr\xeamios altos, mas devolvem perdas ainda maiores ao longo do tempo; os outros dois pagam menos por carta, mas continuam lucrativos no longo prazo. Sua miss\xe3o \xe9 farejar quais baralhos s\xe3o realmente bons e continuar escolhendo-os.",benefit:"Treina a tomada de decis\xe3o sob incerteza: pesar a recompensa imediata contra a puni\xe7\xe3o adiada, aprender com o feedback e resistir \xe0 atra\xe7\xe3o de um ganho chamativo de curto prazo em favor da aposta mais est\xe1vel de longo prazo.",history:"Vem diretamente da neuroci\xeancia cl\xednica. Pesquisadores da Universidade de Iowa a criaram em 1994 para explicar por que pacientes com les\xe3o no c\xf3rtex pr\xe9-frontal ventromedial continuavam tomando decis\xf5es ruinosas na vida real apesar de um QI normal. Tornou-se uma das tarefas de tomada de decis\xe3o mais citadas da psicologia, usada em estudos sobre depend\xeancia, jogo patol\xf3gico e impulsividade.",creator:"Criada em 1994 por Antoine Bechara junto com Antonio Damasio, Hanna Damasio e Steven Anderson na Universidade de Iowa, de onde vem o nome. Foi concebida como instrumento de pesquisa e cl\xednico, n\xe3o como um jogo de treino cerebral.",methods:"Encare as primeiras cartas como pura reconhecimento de terreno e conte com perder um pouco enquanto mapeia os baralhos. Preste aten\xe7\xe3o ao resultado l\xedquido ao longo de uma sequ\xeancia de cartas, n\xe3o a um \xfanico pr\xeamio isolado, e desconfie de um baralho que paga alto. Observe tamb\xe9m o ritmo das perdas: um baralho cujas puni\xe7\xf5es s\xe3o raras mas enormes pode drenar voc\xea em sil\xeancio, ent\xe3o n\xe3o deixe que a dor pouco frequente o engane fazendo-o achar que ele \xe9 seguro.",duration:"As sess\xf5es s\xe3o naturalmente curtas, da ordem de uma centena de cartas escolhidas ou alguns minutos. Algumas partidas espalhadas por v\xe1rios dias bastam para ver sua estrat\xe9gia ficar mais afiada; n\xe3o h\xe1 sentido em insistir nisso por horas de uma vez s\xf3.",research:"O que \xe9 s\xf3lido \xe9 restrito: as pessoas, e voc\xea, melhoram nesta tarefa espec\xedfica \xe0 medida que os baralhos bons e ruins se revelam pelo feedback, e grupos cl\xednicos escolhem de forma confiavelmente pior que pessoas saud\xe1veis, raz\xe3o pela qual ela continua \xfatil como avalia\xe7\xe3o. A famosa afirma\xe7\xe3o de que as pessoas decidem bem 'antes de saber' a estrat\xe9gia, guiadas por sinais corporais do instinto, \xe9 contestada. Maia e McClelland (2004) descobriram que os participantes em geral t\xeam sim conhecimento consciente, e muitos estudos relatam pessoas saud\xe1veis preferindo o baralho de perdas raras mesmo que ele d\xea preju\xedzo no longo prazo. Portanto, a hist\xf3ria mais profunda do marcador som\xe1tico est\xe1 longe de resolvida, e n\xe3o h\xe1 boas evid\xeancias de que treinar isso o torne um tomador de decis\xf5es mais s\xe1bio na vida real.",rec:"Ignore o tamanho de qualquer ganho isolado e julgue cada baralho apenas por onde ele deixa seu saldo depois de muitas cartas.",faq:[["Existe um baralho que eu deveria sempre escolher?","N\xe3o h\xe1 resposta fixa, porque os baralhos s\xe3o definidos pelo padr\xe3o de pagamento, n\xe3o pela posi\xe7\xe3o. Dois baralhos s\xe3o lucrativos ao longo de muitas cartas e dois n\xe3o s\xe3o; sua tarefa a cada partida \xe9 descobrir quais s\xe3o quais pelos ganhos e perdas e ent\xe3o ficar com os bons."],["Continuo escolhendo o baralho com a perda rara e grande. Estou fazendo errado?","Voc\xea est\xe1 caindo numa armadilha bem documentada. Um baralho que pune apenas de vez em quando parece seguro, mas suas perdas isoladas podem superar todos os seus ganhos. Acompanhe seu saldo acumulado em vez de quantas vezes um baralho o belisca."],["Jogar isto vai me deixar melhor com dinheiro de verdade ou com decis\xf5es de vida?","Sinceramente, n\xe3o h\xe1 boas evid\xeancias disso. Voc\xea ficar\xe1 melhor em ler estes baralhos, mas a transfer\xeancia ampla para escolhas financeiras ou de vida reais n\xe3o est\xe1 comprovada. Encare como um exerc\xedcio focado de pensamento sobre recompensa adiada, n\xe3o como uma melhoria de vida."]],variants:"Varia\xe7\xf5es comuns mudam o n\xfamero de baralhos, alternam se os baralhos ruins punem voc\xea com frequ\xeancia ou raramente, invertem para uma vers\xe3o que come\xe7a com perda em que voc\xea arranca endividado, encurtam ou alongam a sequ\xeancia, ou acrescentam uma vers\xe3o que pergunta o qu\xe3o confiante voc\xea est\xe1, para que os pesquisadores investiguem o que voc\xea sabe conscientemente."},hi:{about:"Iowa: 4 Decks \u090f\u0915 \u0915\u093e\u0930\u094d\u0921-\u091c\u0941\u090f \u0935\u093e\u0932\u093e \u0915\u093e\u0930\u094d\u092f \u0939\u0948 \u091c\u093f\u0938\u092e\u0947\u0902 \u091a\u093e\u0930 \u0922\u0915\u0947 \u0939\u0941\u090f (\u0928\u0940\u091a\u0947 \u0915\u0940 \u0913\u0930 \u092e\u0941\u0901\u0939 \u0915\u093f\u090f) \u0922\u0947\u0930 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902\u0964 \u0939\u0930 \u092c\u093e\u0930\u0940 \u092a\u0930 \u0906\u092a \u0915\u093f\u0938\u0940 \u092d\u0940 \u0922\u0947\u0930 \u0938\u0947 \u090f\u0915 \u0915\u093e\u0930\u094d\u0921 \u0909\u0920\u093e\u0924\u0947 \u0939\u0948\u0902, \u0915\u0941\u091b \u0928\u0915\u0932\u0940 \u092a\u0948\u0938\u0947 \u091c\u0940\u0924\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u0915\u092d\u0940-\u0915\u092d\u0940 \u0909\u0938\u0915\u093e \u090f\u0915 \u092c\u0921\u093c\u093e \u0939\u093f\u0938\u094d\u0938\u093e \u0917\u0901\u0935\u093e \u092d\u0940 \u0926\u0947\u0924\u0947 \u0939\u0948\u0902\u0964 \u0926\u094b \u0922\u0947\u0930 \u0906\u092a\u0915\u094b \u092c\u0921\u093c\u0947 \u0907\u0928\u093e\u092e \u0915\u093e \u0932\u093e\u0932\u091a \u0926\u0947\u0924\u0947 \u0939\u0948\u0902, \u092e\u0917\u0930 \u0938\u092e\u092f \u0915\u0947 \u0938\u093e\u0925 \u0909\u0938\u0938\u0947 \u092d\u0940 \u092c\u0921\u093c\u093e \u0928\u0941\u0915\u0938\u093e\u0928 \u0932\u094c\u091f\u093e\u0924\u0947 \u0939\u0948\u0902; \u092c\u093e\u0915\u0940 \u0926\u094b \u0922\u0947\u0930 \u092a\u094d\u0930\u0924\u093f \u0915\u093e\u0930\u094d\u0921 \u0915\u092e \u0926\u0947\u0924\u0947 \u0939\u0948\u0902, \u092a\u0930 \u0932\u0902\u092c\u0940 \u0926\u094c\u0921\u093c \u092e\u0947\u0902 \u092b\u093c\u093e\u092f\u0926\u0947\u092e\u0902\u0926 \u092c\u0928\u0947 \u0930\u0939\u0924\u0947 \u0939\u0948\u0902\u0964 \u0906\u092a\u0915\u093e \u0915\u093e\u092e \u0939\u0948 \u092e\u0939\u0938\u0942\u0938 \u0915\u0930\u0915\u0947 \u092a\u0939\u091a\u093e\u0928\u0928\u093e \u0915\u093f \u0905\u0938\u0932 \u092e\u0947\u0902 \u0915\u094c\u0928-\u0938\u0947 \u0922\u0947\u0930 \u0905\u091a\u094d\u091b\u0947 \u0939\u0948\u0902 \u0914\u0930 \u0932\u0917\u093e\u0924\u093e\u0930 \u0935\u0939\u0940 \u091a\u0941\u0928\u0924\u0947 \u0930\u0939\u0928\u093e\u0964",benefit:"\u092f\u0939 \u0905\u0928\u093f\u0936\u094d\u091a\u093f\u0924\u0924\u093e \u0915\u0947 \u092c\u0940\u091a \u0928\u093f\u0930\u094d\u0923\u092f \u0932\u0947\u0928\u0947 \u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0930\u093e\u0924\u093e \u0939\u0948: \u0924\u0941\u0930\u0902\u0924 \u092e\u093f\u0932\u0928\u0947 \u0935\u093e\u0932\u0947 \u0907\u0928\u093e\u092e \u0914\u0930 \u092c\u093e\u0926 \u092e\u0947\u0902 \u0906\u0928\u0947 \u0935\u093e\u0932\u0940 \u0938\u091c\u093c\u093e \u0915\u0947 \u092c\u0940\u091a \u0924\u094c\u0932 \u0915\u0930\u0928\u093e, \u092b\u093c\u0940\u0921\u092c\u0948\u0915 \u0938\u0947 \u0938\u0940\u0916\u0928\u093e, \u0914\u0930 \u0915\u093f\u0938\u0940 \u091a\u092e\u0915\u0940\u0932\u0940 \u0905\u0932\u094d\u092a\u0915\u093e\u0932\u093f\u0915 \u091c\u0940\u0924 \u0915\u0947 \u0916\u093f\u0902\u091a\u093e\u0935 \u092a\u0930 \u0915\u093e\u092c\u0942 \u092a\u093e\u0915\u0930 \u0927\u0940\u092e\u0947-\u0938\u094d\u0925\u093f\u0930 \u0926\u0940\u0930\u094d\u0918\u0915\u093e\u0932\u093f\u0915 \u0926\u093e\u0901\u0935 \u0915\u094b \u091a\u0941\u0928\u0928\u093e\u0964",history:"\u092f\u0939 \u0938\u0940\u0927\u0947 \u091a\u093f\u0915\u093f\u0924\u094d\u0938\u0915\u0940\u092f \u0924\u0902\u0924\u094d\u0930\u093f\u0915\u093e-\u0935\u093f\u091c\u094d\u091e\u093e\u0928 (\u0915\u094d\u0932\u093f\u0928\u093f\u0915\u0932 \u0928\u094d\u092f\u0942\u0930\u094b\u0938\u093e\u0907\u0902\u0938) \u0938\u0947 \u0906\u092f\u093e \u0939\u0948\u0964 \u0906\u092f\u094b\u0935\u093e \u0935\u093f\u0936\u094d\u0935\u0935\u093f\u0926\u094d\u092f\u093e\u0932\u092f \u0915\u0947 \u0936\u094b\u0927\u0915\u0930\u094d\u0924\u093e\u0913\u0902 \u0928\u0947 \u0907\u0938\u0947 1994 \u092e\u0947\u0902 \u092c\u0928\u093e\u092f\u093e \u0924\u093e\u0915\u093f \u092f\u0939 \u0938\u092e\u091d\u093e\u092f\u093e \u091c\u093e \u0938\u0915\u0947 \u0915\u093f \u0935\u0947\u0902\u091f\u094d\u0930\u094b\u092e\u0940\u0921\u093f\u092f\u0932 \u092a\u094d\u0930\u0940\u092b\u093c\u094d\u0930\u0902\u091f\u0932 \u0915\u0949\u0930\u094d\u091f\u0947\u0915\u094d\u0938 \u092e\u0947\u0902 \u0915\u094d\u0937\u0924\u093f \u0935\u093e\u0932\u0947 \u0930\u094b\u0917\u0940 \u0938\u093e\u092e\u093e\u0928\u094d\u092f IQ \u0915\u0947 \u092c\u093e\u0935\u091c\u0942\u0926 \u0905\u0938\u0932 \u091c\u093c\u093f\u0902\u0926\u0917\u0940 \u092e\u0947\u0902 \u092c\u093e\u0930-\u092c\u093e\u0930 \u0935\u093f\u0928\u093e\u0936\u0915\u093e\u0930\u0940 \u091a\u0941\u0928\u093e\u0935 \u0915\u094d\u092f\u094b\u0902 \u0915\u0930\u0924\u0947 \u0930\u0939\u0924\u0947 \u0939\u0948\u0902\u0964 \u0906\u0917\u0947 \u091a\u0932\u0915\u0930 \u092f\u0939 \u092e\u0928\u094b\u0935\u093f\u091c\u094d\u091e\u093e\u0928 \u092e\u0947\u0902 \u0928\u093f\u0930\u094d\u0923\u092f-\u0932\u0947\u0928\u0947 \u0935\u093e\u0932\u0947 \u0938\u092c\u0938\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0909\u0926\u094d\u0927\u0943\u0924 \u0915\u093e\u0930\u094d\u092f\u094b\u0902 \u092e\u0947\u0902 \u0938\u0947 \u090f\u0915 \u092c\u0928 \u0917\u092f\u093e, \u091c\u093f\u0938\u0915\u093e \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0928\u0936\u0947, \u091c\u0941\u090f \u0914\u0930 \u0906\u0935\u0947\u0917 (\u0907\u092e\u094d\u092a\u0932\u094d\u0938\u093f\u0935\u093f\u091f\u0940) \u0915\u0947 \u0905\u0927\u094d\u092f\u092f\u0928\u094b\u0902 \u092e\u0947\u0902 \u0939\u094b\u0924\u093e \u0939\u0948\u0964",creator:"\u0907\u0938\u0947 1994 \u092e\u0947\u0902 Antoine Bechara \u0928\u0947 Antonio Damasio, Hanna Damasio \u0914\u0930 Steven Anderson \u0915\u0947 \u0938\u093e\u0925 \u0906\u092f\u094b\u0935\u093e \u0935\u093f\u0936\u094d\u0935\u0935\u093f\u0926\u094d\u092f\u093e\u0932\u092f \u092e\u0947\u0902 \u092c\u0928\u093e\u092f\u093e, \u0914\u0930 \u0935\u0939\u0940\u0902 \u0938\u0947 \u0907\u0938\u0915\u093e \u0928\u093e\u092e \u092a\u0921\u093c\u093e\u0964 \u0907\u0938\u0947 \u090f\u0915 \u0936\u094b\u0927 \u0914\u0930 \u091a\u093f\u0915\u093f\u0924\u094d\u0938\u0915\u0940\u092f \u0909\u092a\u0915\u0930\u0923 \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u0930\u091a\u093e \u0917\u092f\u093e \u0925\u093e, \u0928 \u0915\u093f \u0926\u093f\u092e\u093e\u0917\u0940 \u0915\u0938\u0930\u0924 \u0935\u093e\u0932\u0947 \u0916\u0947\u0932 \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902\u0964",methods:"\u0936\u0941\u0930\u0941\u0906\u0924\u0940 \u0915\u093e\u0930\u094d\u0921\u094b\u0902 \u0915\u094b \u0935\u093f\u0936\u0941\u0926\u094d\u0927 \u091f\u094b\u0939 \u0932\u0947\u0928\u093e \u092e\u093e\u0928\u093f\u090f \u0914\u0930 \u092f\u0939 \u0909\u092e\u094d\u092e\u0940\u0926 \u0930\u0916\u093f\u090f \u0915\u093f \u0922\u0947\u0930\u094b\u0902 \u0915\u093e \u0928\u0915\u094d\u0936\u093e \u092c\u0928\u093e\u0924\u0947 \u0939\u0941\u090f \u0925\u094b\u0921\u093c\u093e \u0928\u0941\u0915\u0938\u093e\u0928 \u0939\u094b\u0917\u093e\u0964 \u0915\u093f\u0938\u0940 \u090f\u0915 \u091c\u0948\u0915\u092a\u0949\u091f \u092a\u0930 \u0928\u0939\u0940\u0902, \u092c\u0932\u094d\u0915\u093f \u0915\u0908 \u0915\u093e\u0930\u094d\u0921\u094b\u0902 \u0915\u0940 \u0926\u094c\u0921\u093c \u092e\u0947\u0902 \u0939\u0941\u090f \u0936\u0941\u0926\u094d\u0927 \u0928\u0924\u0940\u091c\u0947 \u092a\u0930 \u0927\u094d\u092f\u093e\u0928 \u0926\u0940\u091c\u093f\u090f, \u0914\u0930 \u092c\u0921\u093c\u093e \u0907\u0928\u093e\u092e \u0926\u0947\u0928\u0947 \u0935\u093e\u0932\u0947 \u0922\u0947\u0930 \u092a\u0930 \u0936\u0915 \u0915\u0940\u091c\u093f\u090f\u0964 \u0928\u0941\u0915\u0938\u093e\u0928 \u0915\u0940 \u0932\u092f \u092a\u0930 \u092d\u0940 \u0928\u091c\u093c\u0930 \u0930\u0916\u093f\u090f: \u091c\u093f\u0938 \u0922\u0947\u0930 \u0915\u0940 \u0938\u091c\u093c\u093e\u090f\u0901 \u0915\u092e \u092a\u0930 \u092c\u0939\u0941\u0924 \u092c\u0921\u093c\u0940 \u0939\u094b\u0924\u0940 \u0939\u0948\u0902, \u0935\u0939 \u091a\u0941\u092a\u091a\u093e\u092a \u0906\u092a\u0915\u093e \u0916\u0942\u0928 \u091a\u0942\u0938 \u0938\u0915\u0924\u093e \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0915\u092d\u0940-\u0915\u092d\u093e\u0930 \u0939\u094b\u0928\u0947 \u0935\u093e\u0932\u0940 \u092a\u0940\u0921\u093c\u093e \u0915\u094b \u0926\u0947\u0916\u0915\u0930 \u0907\u0938\u0947 \u0938\u0941\u0930\u0915\u094d\u0937\u093f\u0924 \u092e\u0924 \u092e\u093e\u0928 \u092c\u0948\u0920\u093f\u090f\u0964",duration:"\u0938\u0924\u094d\u0930 \u0938\u094d\u0935\u092d\u093e\u0935 \u0938\u0947 \u0939\u0940 \u091b\u094b\u091f\u0947 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902, \u0915\u0930\u0940\u092c \u0938\u094c \u0915\u093e\u0930\u094d\u0921 \u0909\u0920\u093e\u0928\u0947 \u092f\u093e \u0915\u0941\u091b \u092e\u093f\u0928\u091f\u094b\u0902 \u0915\u0947\u0964 \u0915\u0941\u091b \u0926\u093f\u0928\u094b\u0902 \u092e\u0947\u0902 \u092b\u0948\u0932\u0940 \u092e\u0941\u091f\u094d\u0920\u0940 \u092d\u0930 \u0926\u094c\u0921\u093c\u0947\u0902 \u0939\u0940 \u0906\u092a\u0915\u0940 \u0930\u0923\u0928\u0940\u0924\u093f \u0915\u094b \u0927\u093e\u0930 \u0926\u0947\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0915\u093e\u092b\u093c\u0940 \u0939\u0948\u0902; \u090f\u0915 \u0939\u0940 \u092c\u0948\u0920\u0915 \u092e\u0947\u0902 \u0918\u0902\u091f\u094b\u0902 \u0907\u0938\u0947 \u092a\u0940\u0938\u0928\u0947 \u0915\u093e \u0915\u094b\u0908 \u0916\u093e\u0938 \u092e\u0924\u0932\u092c \u0928\u0939\u0940\u0902\u0964",research:"\u091c\u094b \u092c\u093e\u0924 \u092a\u0915\u094d\u0915\u0940 \u0939\u0948 \u0935\u0939 \u0938\u0940\u092e\u093f\u0924 \u0939\u0948: \u0932\u094b\u0917, \u0914\u0930 \u0906\u092a \u092d\u0940, \u0907\u0938\u0940 \u0916\u093e\u0938 \u0915\u093e\u0930\u094d\u092f \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b\u0924\u0947 \u091c\u093e\u0924\u0947 \u0939\u0948\u0902 \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u092b\u093c\u0940\u0921\u092c\u0948\u0915 \u0915\u0947 \u091c\u093c\u0930\u093f\u090f \u0905\u091a\u094d\u091b\u0947 \u0914\u0930 \u092c\u0941\u0930\u0947 \u0922\u0947\u0930 \u0909\u091c\u093e\u0917\u0930 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u091a\u093f\u0915\u093f\u0924\u094d\u0938\u0915\u0940\u092f \u0938\u092e\u0942\u0939 \u0938\u094d\u0935\u0938\u094d\u0925 \u0932\u094b\u0917\u094b\u0902 \u0915\u0947 \u092e\u0941\u0915\u093e\u092c\u0932\u0947 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0922\u0902\u0917 \u0938\u0947 \u092c\u0926\u0924\u0930 \u091a\u0941\u0928\u093e\u0935 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902 \u2014 \u0907\u0938\u0940\u0932\u093f\u090f \u092f\u0939 \u0906\u0915\u0932\u0928 \u0915\u0947 \u0924\u094c\u0930 \u092a\u0930 \u0909\u092a\u092f\u094b\u0917\u0940 \u092c\u0928\u093e \u0930\u0939\u0924\u093e \u0939\u0948\u0964 \u092f\u0939 \u092e\u0936\u0939\u0942\u0930 \u0926\u093e\u0935\u093e \u0915\u093f \u0932\u094b\u0917 \u0930\u0923\u0928\u0940\u0924\u093f '\u091c\u093e\u0928\u0928\u0947 \u0938\u0947 \u092a\u0939\u0932\u0947' \u0939\u0940, \u0905\u0902\u0926\u0930\u0942\u0928\u0940 \u0936\u093e\u0930\u0940\u0930\u093f\u0915 \u0938\u0902\u0915\u0947\u0924\u094b\u0902 \u0915\u0947 \u092c\u0932 \u092a\u0930, \u0905\u091a\u094d\u091b\u093e \u092b\u093c\u0948\u0938\u0932\u093e \u0915\u0930 \u0932\u0947\u0924\u0947 \u0939\u0948\u0902 \u2014 \u0935\u093f\u0935\u093e\u0926\u093f\u0924 \u0939\u0948\u0964 Maia \u0914\u0930 McClelland (2004) \u0928\u0947 \u092a\u093e\u092f\u093e \u0915\u093f \u092a\u094d\u0930\u0924\u093f\u092d\u093e\u0917\u093f\u092f\u094b\u0902 \u0915\u094b \u0906\u092e\u0924\u094c\u0930 \u092a\u0930 \u0938\u091a\u0947\u0924 \u091c\u094d\u091e\u093e\u0928 \u0939\u094b\u0924\u093e \u0939\u0940 \u0939\u0948, \u0914\u0930 \u0915\u0908 \u0905\u0927\u094d\u092f\u092f\u0928 \u092c\u0924\u093e\u0924\u0947 \u0939\u0948\u0902 \u0915\u093f \u0938\u094d\u0935\u0938\u094d\u0925 \u0932\u094b\u0917 \u0915\u092e \u0928\u0941\u0915\u0938\u093e\u0928 \u0935\u093e\u0932\u0947 \u0922\u0947\u0930 \u0915\u094b \u0924\u0930\u091c\u0940\u0939 \u0926\u0947\u0924\u0947 \u0939\u0948\u0902 \u092d\u0932\u0947 \u0939\u0940 \u0935\u0939 \u0932\u0902\u092c\u0940 \u0926\u094c\u0921\u093c \u092e\u0947\u0902 \u0918\u093e\u091f\u0947 \u0915\u093e \u0939\u094b \u2014 \u0907\u0938\u0932\u093f\u090f \u0917\u0939\u0930\u0940 \u0938\u094b\u092e\u0948\u091f\u093f\u0915-\u092e\u093e\u0930\u094d\u0915\u0930 \u0935\u093e\u0932\u0940 \u0915\u0939\u093e\u0928\u0940 \u0915\u0924\u0908 \u0924\u092f \u0928\u0939\u0940\u0902 \u0939\u0941\u0908 \u0939\u0948, \u0914\u0930 \u0907\u0938\u0915\u093e \u0915\u094b\u0908 \u0905\u091a\u094d\u091b\u093e \u0938\u092c\u0942\u0924 \u0928\u0939\u0940\u0902 \u0915\u093f \u0907\u0938\u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0906\u092a\u0915\u094b \u0905\u0938\u0932 \u091c\u093c\u093f\u0902\u0926\u0917\u0940 \u092e\u0947\u0902 \u0938\u092e\u091d\u0926\u093e\u0930 \u0928\u093f\u0930\u094d\u0923\u092f-\u0932\u0947\u0928\u0947 \u0935\u093e\u0932\u093e \u092c\u0928\u093e \u0926\u0947\u0924\u093e \u0939\u0948\u0964",rec:"\u0915\u093f\u0938\u0940 \u092d\u0940 \u090f\u0915 \u091c\u0940\u0924 \u0915\u0947 \u0906\u0915\u093e\u0930 \u0915\u094b \u0905\u0928\u0926\u0947\u0916\u093e \u0915\u0940\u091c\u093f\u090f \u0914\u0930 \u0939\u0930 \u0922\u0947\u0930 \u0915\u094b \u0938\u093f\u0930\u094d\u092b\u093c \u0907\u0938 \u092c\u093e\u0924 \u0938\u0947 \u0906\u0901\u0915\u093f\u090f \u0915\u093f \u0915\u0908 \u0915\u093e\u0930\u094d\u0921\u094b\u0902 \u0915\u0947 \u092c\u093e\u0926 \u0935\u0939 \u0906\u092a\u0915\u0947 \u092c\u0948\u0932\u0947\u0902\u0938 \u0915\u094b \u0915\u0939\u093e\u0901 \u091b\u094b\u0921\u093c\u0924\u093e \u0939\u0948\u0964",faq:[["\u0915\u094d\u092f\u093e \u0915\u094b\u0908 \u0910\u0938\u093e \u0922\u0947\u0930 \u0939\u0948 \u091c\u093f\u0938\u0947 \u092e\u0941\u091d\u0947 \u0939\u092e\u0947\u0936\u093e \u091a\u0941\u0928 \u0939\u0940 \u0932\u0947\u0928\u093e \u091a\u093e\u0939\u093f\u090f?","\u0915\u094b\u0908 \u0924\u092f \u091c\u0935\u093e\u092c \u0928\u0939\u0940\u0902, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u0922\u0947\u0930\u094b\u0902 \u0915\u0940 \u092a\u0939\u091a\u093e\u0928 \u0909\u0928\u0915\u0940 \u091c\u0917\u0939 \u0938\u0947 \u0928\u0939\u0940\u0902, \u092c\u0932\u094d\u0915\u093f \u0909\u0928\u0915\u0947 \u092d\u0941\u0917\u0924\u093e\u0928-\u092a\u0948\u091f\u0930\u094d\u0928 \u0938\u0947 \u0939\u094b\u0924\u0940 \u0939\u0948\u0964 \u0926\u094b \u0922\u0947\u0930 \u0915\u0908 \u0915\u093e\u0930\u094d\u0921\u094b\u0902 \u092e\u0947\u0902 \u092b\u093c\u093e\u092f\u0926\u0947\u092e\u0902\u0926 \u0939\u0948\u0902 \u0914\u0930 \u0926\u094b \u0928\u0939\u0940\u0902; \u0939\u0930 \u0916\u0947\u0932 \u092e\u0947\u0902 \u0906\u092a\u0915\u093e \u0915\u093e\u092e \u0939\u0948 \u091c\u0940\u0924-\u0939\u093e\u0930 \u0938\u0947 \u092a\u0924\u093e \u0932\u0917\u093e\u0928\u093e \u0915\u093f \u0915\u094c\u0928 \u0915\u094c\u0928-\u0938\u093e \u0939\u0948, \u092b\u093f\u0930 \u0905\u091a\u094d\u091b\u0947 \u0935\u093e\u0932\u0947 \u0938\u0947 \u091a\u093f\u092a\u0915\u0947 \u0930\u0939\u0928\u093e\u0964"],["\u092e\u0948\u0902 \u092c\u093e\u0930-\u092c\u093e\u0930 \u0909\u0938\u0940 \u0922\u0947\u0930 \u0915\u094b \u091a\u0941\u0928\u0924\u093e \u0930\u0939\u0924\u093e \u0939\u0942\u0901 \u091c\u093f\u0938\u092e\u0947\u0902 \u0915\u092d\u0940-\u0915\u092d\u093e\u0930 \u092c\u0921\u093c\u093e \u0928\u0941\u0915\u0938\u093e\u0928 \u0939\u094b\u0924\u093e \u0939\u0948\u0964 \u0915\u094d\u092f\u093e \u092e\u0948\u0902 \u0917\u0932\u0924 \u0915\u0930 \u0930\u0939\u093e \u0939\u0942\u0901?","\u0906\u092a \u090f\u0915 \u092d\u0932\u0940\u092d\u093e\u0901\u0924\u093f \u092a\u094d\u0930\u0932\u0947\u0916\u093f\u0924 \u091c\u093e\u0932 \u092e\u0947\u0902 \u092b\u0901\u0938 \u0930\u0939\u0947 \u0939\u0948\u0902\u0964 \u091c\u094b \u0922\u0947\u0930 \u0938\u093f\u0930\u094d\u092b\u093c \u0915\u092d\u0940-\u0915\u092d\u0940 \u0938\u091c\u093c\u093e \u0926\u0947\u0924\u093e \u0939\u0948 \u0935\u0939 \u0938\u0941\u0930\u0915\u094d\u0937\u093f\u0924 \u0932\u0917\u0924\u093e \u0939\u0948, \u092b\u093f\u0930 \u092d\u0940 \u0909\u0938\u0915\u093e \u090f\u0915 \u0939\u0940 \u0928\u0941\u0915\u0938\u093e\u0928 \u0909\u0938\u0915\u0940 \u0938\u093e\u0930\u0940 \u091c\u0940\u0924\u094b\u0902 \u092a\u0930 \u092d\u093e\u0930\u0940 \u092a\u0921\u093c \u0938\u0915\u0924\u093e \u0939\u0948\u0964 \u092f\u0939 \u0926\u0947\u0916\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u0915\u093f \u0915\u094b\u0908 \u0922\u0947\u0930 \u0915\u093f\u0924\u0928\u0940 \u092c\u093e\u0930 \u0921\u0902\u0915 \u092e\u093e\u0930\u0924\u093e \u0939\u0948, \u0905\u092a\u0928\u0947 \u091a\u0932\u0924\u0947-\u0915\u0941\u0932 \u092f\u094b\u0917 \u092a\u0930 \u0928\u091c\u093c\u0930 \u0930\u0916\u093f\u090f\u0964"],["\u0915\u094d\u092f\u093e \u092f\u0939 \u0916\u0947\u0932\u0928\u0947 \u0938\u0947 \u092e\u0948\u0902 \u0905\u0938\u0932 \u0926\u0941\u0928\u093f\u092f\u093e \u0915\u0947 \u092a\u0948\u0938\u0947 \u092f\u093e \u091c\u093c\u093f\u0902\u0926\u0917\u0940 \u0915\u0947 \u092b\u093c\u0948\u0938\u0932\u094b\u0902 \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u090a\u0901\u0917\u093e?","\u0908\u092e\u093e\u0928\u0926\u093e\u0930\u0940 \u0938\u0947 \u0915\u0939\u0947\u0902 \u0924\u094b \u0907\u0938\u0915\u093e \u0915\u094b\u0908 \u0905\u091a\u094d\u091b\u093e \u0938\u092c\u0942\u0924 \u0928\u0939\u0940\u0902 \u0939\u0948\u0964 \u0906\u092a \u0907\u0928 \u0922\u0947\u0930\u094b\u0902 \u0915\u094b \u092a\u0922\u093c\u0928\u0947 \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b\u0902\u0917\u0947, \u092e\u0917\u0930 \u0905\u0938\u0932 \u0935\u093f\u0924\u094d\u0924\u0940\u092f \u092f\u093e \u091c\u0940\u0935\u0928 \u0915\u0947 \u091a\u0941\u0928\u093e\u0935\u094b\u0902 \u0924\u0915 \u0935\u094d\u092f\u093e\u092a\u0915 \u0939\u0938\u094d\u0924\u093e\u0902\u0924\u0930\u0923 \u0938\u093e\u092c\u093f\u0924 \u0928\u0939\u0940\u0902 \u0939\u0941\u0906 \u0939\u0948\u0964 \u0907\u0938\u0947 \u0935\u093f\u0932\u0902\u092c\u093f\u0924-\u0907\u0928\u093e\u092e \u0935\u093e\u0932\u0940 \u0938\u094b\u091a \u0915\u0940 \u090f\u0915 \u0915\u0947\u0902\u0926\u094d\u0930\u093f\u0924 \u0915\u0938\u0930\u0924 \u092e\u093e\u0928\u093f\u090f, \u091c\u093c\u093f\u0902\u0926\u0917\u0940 \u0915\u093e \u0905\u092a\u0917\u094d\u0930\u0947\u0921 \u0928\u0939\u0940\u0902\u0964"]],variants:"\u0906\u092e \u092c\u0926\u0932\u093e\u0935 \u0922\u0947\u0930\u094b\u0902 \u0915\u0940 \u0938\u0902\u0916\u094d\u092f\u093e \u0915\u094b \u092c\u0926\u0932\u0924\u0947 \u0939\u0948\u0902, \u092f\u0939 \u0909\u0932\u091f \u0926\u0947\u0924\u0947 \u0939\u0948\u0902 \u0915\u093f \u092c\u0941\u0930\u0947 \u0922\u0947\u0930 \u0906\u092a\u0915\u094b \u092c\u093e\u0930-\u092c\u093e\u0930 \u0938\u091c\u093c\u093e \u0926\u0947\u0902 \u092f\u093e \u0915\u092d\u0940-\u0915\u092d\u093e\u0930, \u0907\u0938\u0947 \u0918\u093e\u091f\u0947-\u0938\u0947-\u0936\u0941\u0930\u0942 \u0935\u093e\u0932\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u092a\u0932\u091f \u0926\u0947\u0924\u0947 \u0939\u0948\u0902 \u091c\u0939\u093e\u0901 \u0906\u092a \u0915\u0930\u094d\u091c\u093c \u092e\u0947\u0902 \u0936\u0941\u0930\u0941\u0906\u0924 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902, \u0926\u094c\u0921\u093c \u0915\u094b \u091b\u094b\u091f\u093e \u092f\u093e \u0932\u0902\u092c\u093e \u0915\u0930\u0924\u0947 \u0939\u0948\u0902, \u092f\u093e \u090f\u0915 \u0910\u0938\u093e \u0930\u0942\u092a \u091c\u094b\u0921\u093c \u0926\u0947\u0924\u0947 \u0939\u0948\u0902 \u091c\u094b \u092a\u0942\u091b\u0924\u093e \u0939\u0948 \u0915\u093f \u0906\u092a \u0915\u093f\u0924\u0928\u0947 \u0906\u0936\u094d\u0935\u0938\u094d\u0924 \u0939\u0948\u0902 \u0924\u093e\u0915\u093f \u0936\u094b\u0927\u0915\u0930\u094d\u0924\u093e \u091f\u091f\u094b\u0932 \u0938\u0915\u0947\u0902 \u0915\u093f \u0906\u092a \u0938\u091a\u0947\u0924 \u0930\u0942\u092a \u0938\u0947 \u0915\u094d\u092f\u093e \u091c\u093e\u0928\u0924\u0947 \u0939\u0948\u0902\u0964"},zh:{about:"\u300a\u7231\u8377\u534e\uff1a\u56db\u526f\u724c\u300b\u662f\u4e00\u4e2a\u7eb8\u724c\u8d4c\u535a\u4efb\u52a1\uff0c\u684c\u9762\u4e0a\u6709\u56db\u526f\u6b63\u9762\u671d\u4e0b\u7684\u724c\u3002\u6bcf\u4e00\u8f6e\u4f60\u4ece\u4efb\u610f\u4e00\u526f\u724c\u91cc\u62bd\u4e00\u5f20\uff0c\u8d62\u5f97\u4e00\u4e9b\u6e38\u620f\u5e01\uff0c\u6709\u65f6\u4e5f\u4f1a\u88ab\u6263\u6389\u4e00\u5927\u7b14\u3002\u5176\u4e2d\u4e24\u526f\u724c\u7528\u9ad8\u989d\u5956\u52b1\u5f15\u8bf1\u4f60\uff0c\u4f46\u957f\u671f\u7b97\u4e0b\u6765\u6263\u56de\u53bb\u7684\u66f4\u591a\uff1b\u53e6\u5916\u4e24\u526f\u6bcf\u5f20\u724c\u8d62\u5f97\u8f83\u5c11\uff0c\u957f\u671f\u5374\u59cb\u7ec8\u76c8\u5229\u3002\u4f60\u7684\u4efb\u52a1\u5c31\u662f\u51ed\u611f\u89c9\u6478\u6e05\u54ea\u51e0\u526f\u724c\u5176\u5b9e\u662f\u597d\u724c\uff0c\u7136\u540e\u575a\u6301\u9009\u5b83\u4eec\u3002",benefit:"\u5b83\u8bad\u7ec3\u7684\u662f\u4e0d\u786e\u5b9a\u60c5\u5883\u4e0b\u7684\u51b3\u7b56\u80fd\u529b\uff1a\u6743\u8861\u773c\u524d\u5956\u52b1\u4e0e\u5ef6\u8fdf\u60e9\u7f5a\uff0c\u4ece\u53cd\u9988\u4e2d\u5b66\u4e60\uff0c\u5e76\u514b\u5236\u4f4f\u90a3\u79cd\u88ab\u4e00\u65f6\u4eae\u773c\u7684\u77ed\u671f\u6536\u76ca\u7275\u7740\u8d70\u7684\u51b2\u52a8\uff0c\u8f6c\u800c\u62bc\u6ce8\u66f4\u7a33\u5065\u7684\u957f\u671f\u56de\u62a5\u3002",history:"\u5b83\u76f4\u63a5\u6765\u81ea\u4e34\u5e8a\u795e\u7ecf\u79d1\u5b66\u30021994\u5e74\uff0c\u7231\u8377\u534e\u5927\u5b66\u7684\u7814\u7a76\u8005\u8bbe\u8ba1\u4e86\u8fd9\u4e2a\u4efb\u52a1\uff0c\u7528\u6765\u89e3\u91ca\u4e3a\u4ec0\u4e48\u8179\u5185\u4fa7\u524d\u989d\u53f6\u76ae\u5c42\u53d7\u635f\u7684\u60a3\u8005\u667a\u5546\u6b63\u5e38\uff0c\u5374\u5728\u73b0\u5b9e\u751f\u6d3b\u4e2d\u4e0d\u65ad\u505a\u51fa\u6bc1\u706d\u6027\u7684\u9009\u62e9\u3002\u5b83\u540e\u6765\u6210\u4e3a\u5fc3\u7406\u5b66\u4e2d\u88ab\u5f15\u7528\u6700\u591a\u7684\u51b3\u7b56\u4efb\u52a1\u4e4b\u4e00\uff0c\u5e7f\u6cdb\u7528\u4e8e\u6210\u763e\u3001\u8d4c\u535a\u548c\u51b2\u52a8\u6027\u7684\u7814\u7a76\u3002",creator:"1994\u5e74\u7531Antoine Bechara\u4e0eAntonio Damasio\u3001Hanna Damasio\u548cSteven Anderson\u5728\u7231\u8377\u534e\u5927\u5b66\u5171\u540c\u8bbe\u8ba1\uff0c\u4efb\u52a1\u540d\u79f0\u4e5f\u7531\u6b64\u800c\u6765\u3002\u5b83\u6700\u521d\u662f\u4f5c\u4e3a\u79d1\u7814\u4e0e\u4e34\u5e8a\u5de5\u5177\u8bbe\u8ba1\u7684\uff0c\u800c\u975e\u4e00\u6b3e\u5065\u8111\u6e38\u620f\u3002",methods:"\u628a\u5f00\u5c40\u7684\u51e0\u5f20\u724c\u5f53\u6210\u7eaf\u7cb9\u7684\u4fa6\u5bdf\uff0c\u5e76\u9884\u671f\u5728\u6478\u6e05\u5404\u526f\u724c\u5e95\u7ec6\u7684\u8fc7\u7a0b\u4e2d\u4f1a\u5c0f\u4e8f\u4e00\u70b9\u3002\u5173\u6ce8\u7684\u662f\u4e00\u8fde\u4e32\u62bd\u724c\u4e4b\u540e\u7684\u51c0\u7ed3\u679c\uff0c\u800c\u4e0d\u662f\u67d0\u4e00\u6b21\u7684\u5927\u5956\uff0c\u5bf9\u90a3\u4e9b\u52a8\u8f84\u7ed9\u4f60\u5927\u989d\u5956\u52b1\u7684\u724c\u8981\u591a\u7559\u4e2a\u5fc3\u773c\u3002\u4e5f\u8981\u7559\u610f\u4e8f\u635f\u7684\u8282\u594f\uff1a\u4e00\u526f\u60e9\u7f5a\u867d\u7136\u7f55\u89c1\u4f46\u6bcf\u6b21\u90fd\u5f88\u60e8\u91cd\u7684\u724c\uff0c\u4f1a\u6084\u65e0\u58f0\u606f\u5730\u628a\u4f60\u69a8\u5e72\uff0c\u522b\u8ba9\u4e0d\u5e38\u51fa\u73b0\u7684\u75db\u611f\u9a97\u4f60\u4ee5\u4e3a\u5b83\u5f88\u5b89\u5168\u3002",duration:"\u5355\u6b21\u6e38\u620f\u5929\u7136\u5c31\u5f88\u77ed\uff0c\u5927\u7ea6\u62bd\u4e00\u767e\u5f20\u724c\u3001\u51e0\u5206\u949f\u800c\u5df2\u3002\u5728\u51e0\u5929\u91cc\u73a9\u4e0a\u51e0\u5c40\uff0c\u5c31\u8db3\u4ee5\u770b\u5230\u4f60\u7684\u7b56\u7565\u9010\u6e10\u78e8\u783a\u51fa\u6765\uff1b\u4e00\u53e3\u6c14\u8fde\u5237\u597d\u51e0\u4e2a\u5c0f\u65f6\u5176\u5b9e\u610f\u4e49\u4e0d\u5927\u3002",research:"\u624e\u5b9e\u7684\u7ed3\u8bba\u8303\u56f4\u5f88\u7a84\uff1a\u968f\u7740\u597d\u724c\u548c\u574f\u724c\u901a\u8fc7\u53cd\u9988\u9010\u6e10\u663e\u5f62\uff0c\u4eba\u4eec\uff08\u5305\u62ec\u4f60\uff09\u4f1a\u8d8a\u6765\u8d8a\u64c5\u957f\u8fd9\u4e2a\u7279\u5b9a\u4efb\u52a1\uff0c\u800c\u4e34\u5e8a\u4eba\u7fa4\u7684\u9009\u62e9\u5219\u53ef\u9760\u5730\u6bd4\u5065\u5eb7\u4eba\u7fa4\u66f4\u5dee\uff0c\u8fd9\u6b63\u662f\u5b83\u81f3\u4eca\u4ecd\u53ef\u7528\u4f5c\u8bc4\u4f30\u5de5\u5177\u7684\u539f\u56e0\u3002\u90a3\u4e2a\u8457\u540d\u7684\u8bba\u65ad\u2014\u2014\u4eba\u4eec\u5728\u51ed\u76f4\u89c9\u7684\u8eab\u4f53\u4fe1\u53f7\u9a71\u52a8\u4e0b\u3001\u4e8e\u300e\u5c1a\u672a\u610f\u8bc6\u5230\u300f\u7b56\u7565\u4e4b\u524d\u5c31\u80fd\u505a\u51fa\u597d\u7684\u51b3\u5b9a\u2014\u2014\u5219\u9887\u5177\u4e89\u8bae\u3002Maia\u548cMcClelland\uff082004\uff09\u53d1\u73b0\u88ab\u8bd5\u901a\u5e38\u786e\u5b9e\u62e5\u6709\u6709\u610f\u8bc6\u7684\u8ba4\u77e5\uff0c\u800c\u4e14\u8bb8\u591a\u7814\u7a76\u90fd\u62a5\u544a\u5065\u5eb7\u4eba\u504f\u7231\u90a3\u526f\u4e8f\u635f\u7f55\u89c1\u5374\u957f\u671f\u8d54\u94b1\u7684\u724c\uff0c\u56e0\u6b64\u66f4\u6df1\u5c42\u7684\u8eaf\u4f53\u6807\u8bb0\u7406\u8bba\u8fdc\u672a\u5b9a\u8bba\uff0c\u4e5f\u6ca1\u6709\u5145\u5206\u8bc1\u636e\u8868\u660e\u53cd\u590d\u7ec3\u4e60\u5b83\u80fd\u8ba9\u4f60\u5728\u73b0\u5b9e\u751f\u6d3b\u4e2d\u6210\u4e3a\u66f4\u660e\u667a\u7684\u51b3\u7b56\u8005\u3002",rec:"\u5ffd\u7565\u4efb\u4f55\u5355\u6b21\u8d62\u5f97\u7684\u5927\u5c0f\uff0c\u53ea\u51ed\u591a\u5f20\u724c\u4e4b\u540e\u4f60\u7684\u4f59\u989d\u843d\u5728\u54ea\u91cc\u6765\u8bc4\u5224\u6bcf\u4e00\u526f\u724c\u3002",faq:[["\u6709\u6ca1\u6709\u54ea\u4e00\u526f\u724c\u6211\u6c38\u8fdc\u9009\u5b83\u5c31\u5bf9\u4e86\uff1f","\u6ca1\u6709\u56fa\u5b9a\u7b54\u6848\uff0c\u56e0\u4e3a\u5404\u526f\u724c\u662f\u7531\u5b83\u4eec\u7684\u6536\u76ca\u6a21\u5f0f\u5b9a\u4e49\u7684\uff0c\u800c\u4e0d\u662f\u7531\u5b83\u4eec\u7684\u4f4d\u7f6e\u3002\u4e24\u526f\u724c\u5728\u591a\u5f20\u4e4b\u540e\u662f\u76c8\u5229\u7684\uff0c\u4e24\u526f\u5219\u4e0d\u662f\uff1b\u4f60\u6bcf\u5c40\u7684\u4efb\u52a1\u5c31\u662f\u4ece\u8f93\u8d62\u4e2d\u53d1\u73b0\u54ea\u526f\u662f\u54ea\u526f\uff0c\u7136\u540e\u575a\u6301\u9009\u90a3\u4e9b\u597d\u724c\u3002"],["\u6211\u8001\u662f\u9009\u90a3\u526f\u5076\u5c14\u624d\u5927\u4e8f\u4e00\u6b21\u7684\u724c\u3002\u6211\u662f\u4e0d\u662f\u505a\u9519\u4e86\uff1f","\u4f60\u6b63\u843d\u5165\u4e00\u4e2a\u6709\u5145\u5206\u8bb0\u5f55\u7684\u9677\u9631\u3002\u4e00\u526f\u53ea\u662f\u5076\u5c14\u624d\u60e9\u7f5a\u4f60\u7684\u724c\u8ba9\u4eba\u611f\u89c9\u5f88\u5b89\u5168\uff0c\u53ef\u5b83\u5355\u6b21\u7684\u4e8f\u635f\u5c31\u80fd\u76d6\u8fc7\u5b83\u6240\u6709\u7684\u8d62\u5229\u3002\u76ef\u7740\u4f60\u7684\u7d2f\u8ba1\u603b\u989d\uff0c\u800c\u4e0d\u662f\u4e00\u526f\u724c\u591a\u4e45\u624d\u54ac\u4f60\u4e00\u53e3\u3002"],["\u73a9\u8fd9\u4e2a\u4f1a\u8ba9\u6211\u5728\u73b0\u5b9e\u4e2d\u7684\u91d1\u94b1\u6216\u4eba\u751f\u51b3\u7b56\u4e0a\u66f4\u9ad8\u660e\u5417\uff1f","\u8bf4\u5b9e\u8bdd\uff0c\u6ca1\u6709\u5145\u5206\u8bc1\u636e\u652f\u6301\u8fd9\u4e00\u70b9\u3002\u4f60\u4f1a\u8d8a\u6765\u8d8a\u64c5\u957f\u8bfb\u61c2\u8fd9\u4e9b\u724c\uff0c\u4f46\u80fd\u5426\u5e7f\u6cdb\u8fc1\u79fb\u5230\u771f\u5b9e\u7684\u8d22\u52a1\u6216\u4eba\u751f\u9009\u62e9\u4e0a\u4ecd\u672a\u5f97\u5230\u8bc1\u5b9e\u3002\u628a\u5b83\u5f53\u4f5c\u4e00\u9879\u4e13\u6ce8\u4e8e\u5ef6\u8fdf\u56de\u62a5\u601d\u7ef4\u7684\u9488\u5bf9\u6027\u7ec3\u4e60\uff0c\u800c\u4e0d\u662f\u4e00\u6b21\u4eba\u751f\u5347\u7ea7\u3002"]],variants:"\u5e38\u89c1\u7684\u53d8\u4f53\u4f1a\u6539\u53d8\u724c\u7684\u526f\u6570\uff0c\u8c03\u6362\u574f\u724c\u662f\u9891\u7e41\u8fd8\u662f\u7f55\u89c1\u5730\u60e9\u7f5a\u4f60\uff0c\u628a\u5b83\u7ffb\u8f6c\u6210\u4ece\u8d1f\u503a\u5f00\u59cb\u7684\u300e\u5148\u4e8f\u540e\u8d62\u300f\u7248\u672c\uff0c\u7f29\u77ed\u6216\u62c9\u957f\u4e00\u5c40\u7684\u957f\u5ea6\uff0c\u6216\u8005\u52a0\u5165\u4e00\u4e2a\u8be2\u95ee\u4f60\u4fe1\u5fc3\u7a0b\u5ea6\u7684\u7248\u672c\uff0c\u597d\u8ba9\u7814\u7a76\u8005\u63a2\u67e5\u4f60\u7a76\u7adf\u6709\u610f\u8bc6\u5730\u77e5\u9053\u4e9b\u4ec0\u4e48\u3002"}},"math-sprint":{ru:{about:"\xabMental Math Sprint\xbb \u2014 \u044d\u0442\u043e \u0430\u0440\u0438\u0444\u043c\u0435\u0442\u0438\u043a\u0430 \u043d\u0430 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c. \u041d\u0430 \u044d\u043a\u0440\u0430\u043d \u043e\u0434\u043d\u0430 \u0437\u0430 \u0434\u0440\u0443\u0433\u043e\u0439 \u0432\u044b\u0441\u043a\u0430\u043a\u0438\u0432\u0430\u044e\u0442 \u043f\u0440\u043e\u0441\u0442\u044b\u0435 \u0437\u0430\u0434\u0430\u0447\u0438 \u043d\u0430 \u0441\u043b\u043e\u0436\u0435\u043d\u0438\u0435, \u0432\u044b\u0447\u0438\u0442\u0430\u043d\u0438\u0435, \u0443\u043c\u043d\u043e\u0436\u0435\u043d\u0438\u0435 \u0438 \u0434\u0435\u043b\u0435\u043d\u0438\u0435, \u0430 \u0432\u0430\u0448\u0430 \u0437\u0430\u0434\u0430\u0447\u0430 \u2014 \u0441\u0447\u0438\u0442\u0430\u0442\u044c \u0432 \u0443\u043c\u0435 \u0438 \u043e\u0442\u0432\u0435\u0447\u0430\u0442\u044c \u043a\u0430\u043a \u043c\u043e\u0436\u043d\u043e \u0431\u044b\u0441\u0442\u0440\u0435\u0435, \u043f\u043e\u043a\u0430 \u043d\u0435 \u0432\u044b\u0448\u043b\u043e \u0432\u0440\u0435\u043c\u044f.",benefit:"\u0422\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u0431\u0435\u0433\u043b\u043e\u0441\u0442\u044c \u0441\u0447\u0451\u0442\u0430: \u0431\u044b\u0441\u0442\u0440\u044b\u0439 \u0434\u043e\u0441\u0442\u0443\u043f \u043a \u0442\u0430\u0431\u043b\u0438\u0446\u0435 \u0441\u043b\u043e\u0436\u0435\u043d\u0438\u044f \u0438 \u0443\u043c\u043d\u043e\u0436\u0435\u043d\u0438\u044f, \u043d\u0430\u0432\u044b\u043a \u043f\u0440\u0438\u043a\u0438\u0434\u043a\u0438 \u0438 \u0443\u043c\u0435\u043d\u0438\u0435 \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0442\u044c \u0438 \u043a\u0440\u0443\u0442\u0438\u0442\u044c \u0447\u0438\u0441\u043b\u0430 \u0432 \u0440\u0430\u0431\u043e\u0447\u0435\u0439 \u043f\u0430\u043c\u044f\u0442\u0438 \u043f\u043e\u0434 \u0434\u0430\u0432\u043b\u0435\u043d\u0438\u0435\u043c \u0442\u0430\u0439\u043c\u0435\u0440\u0430. \u0421\u0430\u043c\u044b\u0439 \u044f\u0432\u043d\u044b\u0439 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442 \u2014 \u0440\u043e\u0441\u0442 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u0438 \u0438 \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u0438 \u0441\u0430\u043c\u043e\u0433\u043e \u0441\u0447\u0451\u0442\u0430.",history:"\u0411\u044b\u0441\u0442\u0440\u044b\u0439 \u0441\u0447\u0451\u0442 \u0432 \u0443\u043c\u0435 \u2014 \u0434\u0440\u0435\u0432\u043d\u0438\u0439 \u043d\u0430\u0432\u044b\u043a, \u043a\u043e\u0442\u043e\u0440\u043e\u043c\u0443 \u0432\u0435\u043a\u0430\u043c\u0438 \u0443\u0447\u0438\u043b\u0438 \u0447\u0435\u0440\u0435\u0437 \u0430\u0431\u0430\u043a \u0438 \u0435\u0433\u043e \u044f\u043f\u043e\u043d\u0441\u043a\u043e\u0433\u043e \u043d\u0430\u0441\u043b\u0435\u0434\u043d\u0438\u043a\u0430 \u0441\u043e\u0440\u043e\u0431\u0430\u043d, \u0447\u0435\u0440\u0435\u0437 \u0432\u0435\u0434\u0438\u0447\u0435\u0441\u043a\u0443\u044e \u043c\u0430\u0442\u0435\u043c\u0430\u0442\u0438\u043a\u0443 \u0438 \u0447\u0435\u0440\u0435\u0437 \u0438\u043c\u0435\u043d\u043d\u044b\u0435 \u0441\u0438\u0441\u0442\u0435\u043c\u044b \u0432\u044b\u0447\u0438\u0441\u043b\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0445 \u043f\u0440\u0438\u0451\u043c\u043e\u0432. \u0424\u043e\u0440\u043c\u0430\u0442 \u043d\u0430 \u0432\u0440\u0435\u043c\u044f \u0432 \u0432\u0438\u0434\u0435 \u0438\u0433\u0440\u044b \u2014 \u0441\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u0430\u044f \u043f\u0435\u0440\u0435\u0434\u0435\u043b\u043a\u0430, \u043a\u043e\u0442\u043e\u0440\u0430\u044f \u0440\u0430\u0437\u043e\u0448\u043b\u0430\u0441\u044c \u0432\u043c\u0435\u0441\u0442\u0435 \u0441 \u043a\u0430\u0440\u043c\u0430\u043d\u043d\u044b\u043c\u0438 \u0438\u0433\u0440\u043e\u0432\u044b\u043c\u0438 \u043f\u0440\u0438\u0441\u0442\u0430\u0432\u043a\u0430\u043c\u0438 \u0438 \u043f\u0440\u0438\u043b\u043e\u0436\u0435\u043d\u0438\u044f\u043c\u0438 \u0434\u043b\u044f \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0438 \u043c\u043e\u0437\u0433\u0430 \u0432 2000-\u0445.",creator:"\u0415\u0434\u0438\u043d\u043e\u0433\u043e \u0430\u0432\u0442\u043e\u0440\u0430 \u043d\u0435\u0442 \u2014 \u0441\u0447\u0451\u0442 \u043d\u0430 \u0432\u0440\u0435\u043c\u044f \u044d\u0442\u043e \u0442\u0438\u043f\u043e\u0432\u043e\u0435 \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u0435, \u0432\u044b\u0440\u043e\u0441\u0448\u0435\u0435 \u0438\u0437 \u0441\u0442\u0430\u0440\u044b\u0445 \u0432\u044b\u0447\u0438\u0441\u043b\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0445 \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u0439. \u0421\u0430\u043c\u044b\u0435 \u0438\u0437\u0432\u0435\u0441\u0442\u043d\u044b\u0435 \u0438\u043c\u0435\u043d\u043d\u044b\u0435 \u0441\u0438\u0441\u0442\u0435\u043c\u044b \u2014 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u0430 \u0441\u043e\u0440\u043e\u0431\u0430\u043d\u0430 (\u044f\u043f\u043e\u043d\u0441\u043a\u043e\u0433\u043e \u0430\u0431\u0430\u043a\u0430) \u0438 \u0441\u0438\u0441\u0442\u0435\u043c\u0430 \u0422\u0440\u0430\u0445\u0442\u0435\u043d\u0431\u0435\u0440\u0433\u0430, \u043d\u0430\u0431\u043e\u0440 \u043f\u0440\u0438\u0451\u043c\u043e\u0432 \u0443\u0441\u0442\u043d\u043e\u0433\u043e \u0441\u0447\u0451\u0442\u0430, \u043f\u0440\u0438\u0434\u0443\u043c\u0430\u043d\u043d\u044b\u0439 \u0438\u043d\u0436\u0435\u043d\u0435\u0440\u043e\u043c \u042f\u043a\u043e\u0431\u043e\u043c \u0422\u0440\u0430\u0445\u0442\u0435\u043d\u0431\u0435\u0440\u0433\u043e\u043c \u0432 1940-\u0445; \u043d\u043e \u0441\u0430\u043c \u0444\u043e\u0440\u043c\u0430\u0442 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u043d\u043e\u0433\u043e \u0441\u0447\u0451\u0442\u0430 \u043d\u0435 \u043f\u0440\u0438\u043d\u0430\u0434\u043b\u0435\u0436\u0438\u0442 \u043d\u0438\u043a\u043e\u043c\u0443 \u043a\u043e\u043d\u043a\u0440\u0435\u0442\u043d\u043e.",methods:"\u0421\u043d\u0430\u0447\u0430\u043b\u0430 \u0432\u044b\u0443\u0447\u0438\u0442\u0435 \u0431\u0430\u0437\u0443 \u043d\u0430\u043c\u0435\u0440\u0442\u0432\u043e \u2014 \u043f\u0430\u0440\u044b \u043d\u0430 \u0441\u043b\u043e\u0436\u0435\u043d\u0438\u0435 \u0438 \u0442\u0430\u0431\u043b\u0438\u0446\u0443 \u0443\u043c\u043d\u043e\u0436\u0435\u043d\u0438\u044f, \u0447\u0442\u043e\u0431\u044b \u043e\u0442\u0432\u0435\u0442 \u0432\u0441\u043f\u043b\u044b\u0432\u0430\u043b \u0441\u0430\u043c. \u041f\u043e\u0442\u043e\u043c \u0434\u043e\u0431\u0430\u0432\u043b\u044f\u0439\u0442\u0435 \u043f\u0440\u0438\u0451\u043c\u044b: \u043e\u043a\u0440\u0443\u0433\u043b\u044f\u0439 \u0438 \u043f\u043e\u043f\u0440\u0430\u0432\u043b\u044f\u0439 (98 + 47 \u043a\u0430\u043a 100 + 47 - 2), \u0440\u0430\u0437\u0431\u0438\u0432\u0430\u0439 \u0447\u0438\u0441\u043b\u043e (7 x 13 \u043a\u0430\u043a 7 x 10 + 7 x 3), \u043f\u0440\u0438\u043a\u0438\u0434\u044b\u0432\u0430\u0439 \u043f\u043e\u0440\u044f\u0434\u043e\u043a \u0434\u043e \u0442\u043e\u0447\u043d\u043e\u0433\u043e \u0441\u0447\u0451\u0442\u0430. \u041e\u0442\u0440\u0430\u0431\u0430\u0442\u044b\u0432\u0430\u0439\u0442\u0435 \u043f\u043e \u043e\u0434\u043d\u043e\u043c\u0443 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044e, \u043f\u043e\u043a\u0430 \u043d\u0435 \u0441\u0442\u0430\u043d\u0435\u0442 \u043b\u0435\u0433\u043a\u043e, \u0438 \u0442\u043e\u043b\u044c\u043a\u043e \u043f\u043e\u0442\u043e\u043c \u0441\u043c\u0435\u0448\u0438\u0432\u0430\u0439\u0442\u0435.",duration:"\u041a\u043e\u0440\u043e\u0442\u043a\u0438\u0435 \u0447\u0430\u0441\u0442\u044b\u0435 \u043f\u043e\u0434\u0445\u043e\u0434\u044b \u0431\u044c\u044e\u0442 \u0434\u043e\u043b\u0433\u0438\u0435. \u041f\u044f\u0442\u044c-\u0434\u0435\u0441\u044f\u0442\u044c \u043c\u0438\u043d\u0443\u0442 \u0432 \u0434\u0435\u043d\u044c \u043f\u043e\u0447\u0442\u0438 \u043a\u0430\u0436\u0434\u044b\u0439 \u0434\u0435\u043d\u044c \u043f\u043e\u0434\u043d\u0438\u043c\u0443\u0442 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u0431\u044b\u0441\u0442\u0440\u0435\u0435, \u0447\u0435\u043c \u0447\u0430\u0441 \u0440\u0430\u0437 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e: \u0434\u043e\u0441\u0442\u0443\u043f \u043a \u0444\u0430\u043a\u0442\u0430\u043c \u043a\u0440\u0435\u043f\u043d\u0435\u0442 \u0437\u0430 \u0441\u0447\u0451\u0442 \u0438\u043d\u0442\u0435\u0440\u0432\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u043f\u043e\u0432\u0442\u043e\u0440\u0435\u043d\u0438\u044f.",research:"\u0414\u043e\u043a\u0430\u0437\u0430\u043d\u043e \u0440\u043e\u0432\u043d\u043e \u0442\u043e, \u0447\u0435\u0433\u043e \u0438 \u0436\u0434\u0451\u0448\u044c: \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0448\u044c \u0441\u0447\u0451\u0442 \u043d\u0430 \u0432\u0440\u0435\u043c\u044f \u2014 \u0441\u0447\u0438\u0442\u0430\u0435\u0448\u044c \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u0438 \u0442\u043e\u0447\u043d\u0435\u0435. \u0417\u0430\u044f\u0432\u043a\u0438 \u043f\u043e\u043a\u0440\u0443\u043f\u043d\u0435\u0435 \u043a\u0443\u0434\u0430 \u0441\u043b\u0430\u0431\u0435\u0435: \u0448\u0438\u0440\u043e\u043a\u0438\u0439 \u043f\u0435\u0440\u0435\u043d\u043e\u0441 \u043d\u0430 \u043e\u0431\u0449\u0438\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0438\u043b\u0438 \u0440\u0430\u0431\u043e\u0447\u0443\u044e \u043f\u0430\u043c\u044f\u0442\u044c \u043f\u043e \u0431\u043e\u043b\u044c\u0448\u0435\u0439 \u0447\u0430\u0441\u0442\u0438 \u043d\u0435 \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0451\u043d, \u0430 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0433\u0440\u043e\u043c\u043a\u0438\u0445 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442\u043e\u0432 \u0438\u0437 \u043c\u0438\u0440\u0430 \xab\u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0438 \u043c\u043e\u0437\u0433\u0430\xbb \u2014 \u0432 \u0442\u043e\u043c \u0447\u0438\u0441\u043b\u0435 \u0438\u0434\u0435\u044f, \u0447\u0442\u043e \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u044f \u043d\u0430 \u0440\u0430\u0431\u043e\u0447\u0443\u044e \u043f\u0430\u043c\u044f\u0442\u044c \u043f\u043e\u0434\u043d\u0438\u043c\u0430\u044e\u0442 \u043f\u043e\u0434\u0432\u0438\u0436\u043d\u044b\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442, \u2014 \u043d\u0435 \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u0435\u043b\u0438\u0441\u044c \u0432 \u0441\u0442\u0440\u043e\u0433\u0438\u0445 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u044f\u0445. \u041a \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f\u043c \xab\u043f\u043e\u0443\u043c\u043d\u0435\u0442\u044c\xbb \u0438\u043b\u0438 \xab\u0437\u0430\u0442\u043e\u0440\u043c\u043e\u0437\u0438\u0442\u044c \u0441\u0442\u0430\u0440\u0435\u043d\u0438\u0435 \u043c\u043e\u0437\u0433\u0430\xbb \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u0435\u0441\u044c \u0441 \u043e\u0441\u0442\u043e\u0440\u043e\u0436\u043d\u043e\u0441\u0442\u044c\u044e: \u043d\u0430\u0434\u0451\u0436\u043d\u0430\u044f \u043e\u0442\u0434\u0430\u0447\u0430 \u2014 \u044d\u0442\u043e \u0441\u0430\u043c \u043d\u0430\u0432\u044b\u043a \u043f\u043b\u044e\u0441, \u0443 \u043c\u043d\u043e\u0433\u0438\u0445, \u043c\u0435\u043d\u044c\u0448\u0435 \u0441\u0442\u0440\u0430\u0445\u0430 \u043f\u0435\u0440\u0435\u0434 \u0447\u0438\u0441\u043b\u0430\u043c\u0438.",rec:"\u0412\u043e\u0437\u044c\u043c\u0438\u0442\u0435 \u043e\u0434\u043d\u043e \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435, \u0432 \u043a\u043e\u0442\u043e\u0440\u043e\u043c \u0432\u044b \u043c\u0435\u0434\u043b\u0435\u043d\u043d\u044b, \u043e\u0442\u0440\u0430\u0431\u0430\u0442\u044b\u0432\u0430\u0439\u0442\u0435 \u0435\u0433\u043e \u043f\u043e \u043f\u044f\u0442\u044c \u0441\u043e\u0431\u0440\u0430\u043d\u043d\u044b\u0445 \u043c\u0438\u043d\u0443\u0442 \u0432 \u0434\u0435\u043d\u044c \u0438 \u043f\u043e\u0434\u043c\u0435\u0448\u0438\u0432\u0430\u0439\u0442\u0435 \u043e\u0441\u0442\u0430\u043b\u044c\u043d\u044b\u0435 \u0442\u043e\u043b\u044c\u043a\u043e \u043a\u043e\u0433\u0434\u0430 \u043e\u043d\u043e \u0441\u0442\u0430\u043d\u0435\u0442 \u0434\u0430\u0432\u0430\u0442\u044c\u0441\u044f \u0431\u0435\u0437 \u0443\u0441\u0438\u043b\u0438\u0439.",faq:[["\u042f \u0441\u0442\u0430\u043d\u0443 \u043b\u0443\u0447\u0448\u0435 \u0432 \u043c\u0430\u0442\u0435\u043c\u0430\u0442\u0438\u043a\u0435 \u0432 \u0446\u0435\u043b\u043e\u043c?","\u0412\u044b \u0441\u0442\u0430\u0431\u0438\u043b\u044c\u043d\u043e \u0441\u0442\u0430\u043d\u0435\u0442\u0435 \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u0438 \u0442\u043e\u0447\u043d\u0435\u0435 \u0432 \u0443\u0441\u0442\u043d\u043e\u043c \u0441\u0447\u0451\u0442\u0435, \u0438 \u044d\u0442\u043e \u043c\u043e\u0436\u0435\u0442 \u0441\u043d\u044f\u0442\u044c \u0441\u0442\u0440\u0430\u0445 \u043f\u0435\u0440\u0435\u0434 \u0447\u0438\u0441\u043b\u0430\u043c\u0438. \u041d\u043e \u0430\u043b\u0433\u0435\u0431\u0440\u0435 \u0438\u043b\u0438 \u0432\u044b\u0441\u0448\u0435\u0439 \u043c\u0430\u0442\u0435\u043c\u0430\u0442\u0438\u043a\u0435 \u044d\u0442\u043e \u0441\u0430\u043c\u043e \u043f\u043e \u0441\u0435\u0431\u0435 \u043d\u0435 \u043d\u0430\u0443\u0447\u0438\u0442, \u0438 \u0441\u0435\u0440\u044c\u0451\u0437\u043d\u044b\u0445 \u0434\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432, \u0447\u0442\u043e \u044d\u0442\u043e \u043f\u043e\u0432\u044b\u0448\u0430\u0435\u0442 \u043e\u0431\u0449\u0438\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442, \u043f\u043e\u0447\u0442\u0438 \u043d\u0435\u0442."],["\u041f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u0442\u044c\u0441\u044f \u043f\u0440\u0438\u0451\u043c\u0430\u043c\u0438 \u0432\u0440\u043e\u0434\u0435 \u043e\u043a\u0440\u0443\u0433\u043b\u0435\u043d\u0438\u044f \u2014 \u044d\u0442\u043e \u043d\u0435 \u0436\u0443\u043b\u044c\u043d\u0438\u0447\u0435\u0441\u0442\u0432\u043e?","\u041d\u0435\u0442. \u041e\u043a\u0440\u0443\u0433\u043b\u0435\u043d\u0438\u0435, \u0440\u0430\u0437\u0431\u0438\u0435\u043d\u0438\u0435 \u0447\u0438\u0441\u0435\u043b \u0438 \u043f\u0440\u0438\u043a\u0438\u0434\u043a\u0430 \u2014 \u0438\u043c\u0435\u043d\u043d\u043e \u0442\u0430\u043a \u0438 \u0441\u0447\u0438\u0442\u0430\u044e\u0442 \u043b\u044e\u0434\u0438 \u0441 \u0431\u0435\u0433\u043b\u044b\u043c \u0441\u0447\u0451\u0442\u043e\u043c. \u0426\u0435\u043b\u044c \u2014 \u0432\u0435\u0440\u043d\u044b\u0439 \u043e\u0442\u0432\u0435\u0442 \u0431\u044b\u0441\u0442\u0440\u043e, \u0430 \u043d\u0435 \u043a\u043e\u043d\u043a\u0440\u0435\u0442\u043d\u0430\u044f \u043f\u0440\u043e\u0446\u0435\u0434\u0443\u0440\u0430, \u0442\u0430\u043a \u0447\u0442\u043e \u0443\u0434\u0430\u0447\u043d\u044b\u0435 \u043f\u0440\u0438\u0451\u043c\u044b \u044d\u0442\u043e \u0438 \u0435\u0441\u0442\u044c \u043d\u0430\u0432\u044b\u043a, \u0430 \u043d\u0435 \u043b\u0430\u0437\u0435\u0439\u043a\u0430."],["\u0427\u0435\u0440\u0435\u0437 \u0441\u043a\u043e\u043b\u044c\u043a\u043e \u044f \u0437\u0430\u043c\u0435\u0447\u0443, \u0447\u0442\u043e \u0441\u0447\u0438\u0442\u0430\u044e \u0431\u044b\u0441\u0442\u0440\u0435\u0435?","\u0411\u043e\u043b\u044c\u0448\u0438\u043d\u0441\u0442\u0432\u043e \u0447\u0443\u0432\u0441\u0442\u0432\u0443\u0435\u0442 \u0440\u0430\u0437\u043d\u0438\u0446\u0443 \u0437\u0430 \u043f\u0430\u0440\u0443 \u043d\u0435\u0434\u0435\u043b\u044c \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u0445 \u0435\u0436\u0435\u0434\u043d\u0435\u0432\u043d\u044b\u0445 \u043f\u043e\u0434\u0445\u043e\u0434\u043e\u0432 \u2014 \u0431\u0430\u0437\u043e\u0432\u044b\u0435 \u0444\u0430\u043a\u0442\u044b \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0437\u0438\u0440\u0443\u044e\u0442\u0441\u044f \u0431\u044b\u0441\u0442\u0440\u043e. \u0421\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u043d\u0430 \u043c\u043d\u043e\u0433\u043e\u0448\u0430\u0433\u043e\u0432\u044b\u0445 \u043f\u0440\u0438\u043c\u0435\u0440\u0430\u0445 \u043f\u0440\u043e\u0434\u043e\u043b\u0436\u0430\u0435\u0442 \u0440\u0430\u0441\u0442\u0438 \u043c\u0435\u0441\u044f\u0446\u0430\u043c\u0438."]],variants:"\u0421\u0440\u0435\u0434\u0438 \u0432\u0430\u0440\u0438\u0430\u0446\u0438\u0439 \u2014 \u0440\u0435\u0436\u0438\u043c\u044b \u043d\u0430 \u043e\u0434\u043d\u043e \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435, \u0441\u043f\u0440\u0438\u043d\u0442\u044b \u0441\u043e \u0441\u043c\u0435\u0448\u0430\u043d\u043d\u044b\u043c\u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044f\u043c\u0438, \u043e\u0431\u0440\u0430\u0442\u043d\u044b\u0439 \u043e\u0442\u0441\u0447\u0451\u0442 \u043f\u0440\u043e\u0442\u0438\u0432 \u0431\u0435\u0441\u043a\u043e\u043d\u0435\u0447\u043d\u043e\u0439 \u0441\u0435\u0440\u0438\u0438, \u043d\u0430\u0440\u0430\u0441\u0442\u0430\u044e\u0449\u0430\u044f \u0441\u043b\u043e\u0436\u043d\u043e\u0441\u0442\u044c \u043f\u043e \u043c\u0435\u0440\u0435 \u0432\u0435\u0440\u043d\u044b\u0445 \u043e\u0442\u0432\u0435\u0442\u043e\u0432 \u0438 \u0440\u0435\u0436\u0438\u043c \u043f\u0440\u0438\u043a\u0438\u0434\u043a\u0438, \u0433\u0434\u0435 \u043d\u0430\u0434\u043e \u0432\u044b\u0431\u0440\u0430\u0442\u044c \u0431\u043b\u0438\u0436\u0430\u0439\u0448\u0438\u0439 \u043e\u0442\u0432\u0435\u0442, \u0430 \u043d\u0435 \u0442\u043e\u0447\u043d\u044b\u0439."},en:{about:"Mental Math Sprint is a timed arithmetic drill. The screen throws a stream of simple problems at you \u2014 addition, subtraction, multiplication, division \u2014 and your job is to solve each one in your head and answer as fast as you can before the clock runs out.",benefit:"It builds arithmetic fluency: faster fact retrieval, quicker estimation, and the ability to hold and manipulate numbers in working memory under time pressure. The clearest gain is speed and accuracy at calculation itself.",history:"Fast mental calculation is an ancient skill, taught for centuries through the abacus and its Japanese descendant the soroban, through Vedic mathematics, and through named shortcut systems. The timed, gamified format is a modern adaptation that took off with handheld games and brain-training apps in the 2000s.",creator:"There is no single inventor \u2014 timed mental arithmetic is a generic exercise rooted in older calculation traditions. The most famous named systematized methods are the soroban (Japanese abacus) practice and the Trachtenberg system, a set of mental-calculation shortcuts devised by engineer Jakow Trachtenberg in the 1940s; the speed-drill format itself belongs to no one.",methods:"Memorize your core facts cold (addition pairs and times tables) so retrieval is automatic, then layer on strategies: round and adjust (98 + 47 as 100 + 47 - 2), break numbers apart (7 x 13 as 7 x 10 + 7 x 3), and estimate before you compute. Train one operation at a time until it feels easy, then mix them.",duration:"Short, frequent sessions beat marathons. Five to ten minutes a day, most days, will move your speed faster than an hour once a week, because fact retrieval strengthens through spaced repetition.",research:"Evidence is strongest for exactly what you would expect \u2014 practise timed arithmetic and you get faster and more accurate at arithmetic. The bigger claims are much weaker: broad transfer to general intelligence or working memory is largely unproven, and several famous brain-training findings, including the idea that working-memory drills raise fluid intelligence, failed to replicate in controlled studies. Treat promises of a smarter brain or prevented decline with caution; the reliable payoff is the skill itself plus, for many people, less anxiety around numbers.",rec:"Pick one operation you are slow at, drill it for five focused minutes daily, and only mix in the others once it feels effortless.",faq:[["Will this make me better at maths overall?","It reliably makes you faster and more accurate at mental arithmetic, and it can ease number anxiety. It will not by itself teach algebra or higher maths, and there is little solid evidence it raises general intelligence."],["Is it cheating to use tricks like rounding?","No \u2014 rounding, splitting numbers apart and estimating are exactly how fluent calculators work. The goal is the right answer fast, not a particular procedure, so good shortcuts are the skill, not a workaround."],["How long until I notice I am faster?","Most people feel a difference within a couple of weeks of short daily practice, because basic facts become automatic quickly. Deeper speed on multi-step problems keeps improving over months."]],variants:"Common variations include single-operation modes, mixed-operation sprints, fixed countdown versus endless streaks, escalating difficulty as you get answers right, and estimation modes where you pick the closest answer rather than the exact one."},es:{about:"Mental Math Sprint es un ejercicio de aritm\xe9tica contrarreloj. La pantalla te lanza un chorro de problemas sencillos \u2014sumas, restas, multiplicaciones, divisiones\u2014 y tu tarea es resolver cada uno de cabeza y responder lo m\xe1s r\xe1pido que puedas antes de que se acabe el tiempo.",benefit:"Desarrolla la fluidez aritm\xe9tica: recuperaci\xf3n m\xe1s r\xe1pida de los hechos num\xe9ricos, estimaci\xf3n m\xe1s \xe1gil y la capacidad de retener y manipular n\xfameros en la memoria de trabajo bajo presi\xf3n de tiempo. La mejora m\xe1s clara es la velocidad y la precisi\xf3n en el propio c\xe1lculo.",history:"El c\xe1lculo mental r\xe1pido es una destreza ancestral, ense\xf1ada durante siglos mediante el \xe1baco y su descendiente japon\xe9s el soroban, mediante las matem\xe1ticas v\xe9dicas y mediante sistemas de atajos con nombre propio. El formato cronometrado y convertido en juego es una adaptaci\xf3n moderna que se populariz\xf3 con las maquinitas port\xe1tiles y las aplicaciones de entrenamiento mental en los a\xf1os 2000.",creator:"No hay un \xfanico inventor: la aritm\xe9tica mental contrarreloj es un ejercicio gen\xe9rico arraigado en tradiciones de c\xe1lculo m\xe1s antiguas. Los m\xe9todos sistematizados m\xe1s famosos con nombre propio son la pr\xe1ctica del soroban (\xe1baco japon\xe9s) y el sistema Trachtenberg, un conjunto de atajos de c\xe1lculo mental ideado por el ingeniero Jakow Trachtenberg en los a\xf1os 40; el formato del ejercicio de velocidad en s\xed no es de nadie.",methods:"Memoriza tus hechos b\xe1sicos a fuego (parejas de sumas y tablas de multiplicar) para que la recuperaci\xf3n sea autom\xe1tica, y luego a\xf1ade estrategias: redondea y ajusta (98 + 47 como 100 + 47 - 2), descomp\xf3n n\xfameros (7 x 13 como 7 x 10 + 7 x 3) y estima antes de calcular. Entrena una operaci\xf3n cada vez hasta que te resulte f\xe1cil, y luego m\xe9zclalas.",duration:"Las sesiones cortas y frecuentes ganan a los maratones. De 5 a 10 minutos al d\xeda, casi todos los d\xedas, har\xe1n avanzar tu velocidad m\xe1s r\xe1pido que una hora una vez por semana, porque la recuperaci\xf3n de hechos se refuerza con la repetici\xf3n espaciada.",research:"La evidencia es m\xe1s fuerte para justo lo que cabr\xeda esperar: practica aritm\xe9tica contrarreloj y ser\xe1s m\xe1s r\xe1pido y preciso en aritm\xe9tica. Las afirmaciones m\xe1s grandes son mucho m\xe1s d\xe9biles: la transferencia amplia a la inteligencia general o a la memoria de trabajo est\xe1 en gran medida sin demostrar, y varios hallazgos famosos del entrenamiento mental, incluida la idea de que los ejercicios de memoria de trabajo elevan la inteligencia fluida, no se replicaron en estudios controlados. Toma con cautela las promesas de un cerebro m\xe1s inteligente o de prevenir el declive; la recompensa fiable es la propia destreza m\xe1s, para mucha gente, menos ansiedad ante los n\xfameros.",rec:"Elige una operaci\xf3n que se te d\xe9 lenta, ejerc\xedtala cinco minutos concentrados al d\xeda, y solo a\xf1ade las dem\xe1s cuando te resulte natural.",faq:[["\xbfEsto me har\xe1 mejor en matem\xe1ticas en general?","Te hace de forma fiable m\xe1s r\xe1pido y preciso en el c\xe1lculo mental, y puede aliviar la ansiedad ante los n\xfameros. Por s\xed solo no te ense\xf1ar\xe1 \xe1lgebra ni matem\xe1ticas superiores, y hay poca evidencia s\xf3lida de que eleve la inteligencia general."],["\xbfEs hacer trampa usar trucos como el redondeo?","No: redondear, descomponer n\xfameros y estimar son exactamente como trabajan los calculistas con soltura. El objetivo es la respuesta correcta y r\xe1pida, no un procedimiento concreto, as\xed que los buenos atajos son la destreza, no un truco para saltarse las reglas."],["\xbfCu\xe1nto tardar\xe9 en notar que voy m\xe1s r\xe1pido?","La mayor\xeda de la gente nota la diferencia en un par de semanas de pr\xe1ctica diaria breve, porque los hechos b\xe1sicos se automatizan enseguida. La mayor velocidad en problemas de varios pasos sigue mejorando durante meses."]],variants:"Las variantes habituales incluyen modos de una sola operaci\xf3n, sprints de operaciones mezcladas, cuenta atr\xe1s fija frente a rachas sin fin, dificultad creciente a medida que aciertas, y modos de estimaci\xf3n en los que eliges la respuesta m\xe1s cercana en lugar de la exacta."},de:{about:"Mental Math Sprint ist eine Rechen\xfcbung auf Zeit. Der Bildschirm wirft dir einen Strom einfacher Aufgaben entgegen \u2014 Addition, Subtraktion, Multiplikation, Division \u2014 und deine Aufgabe ist es, jede im Kopf zu l\xf6sen und so schnell wie m\xf6glich zu antworten, bevor die Uhr abl\xe4uft.",benefit:"Sie baut Rechensicherheit auf: schnelleres Abrufen von Fakten, flotteres Absch\xe4tzen und die F\xe4higkeit, Zahlen unter Zeitdruck im Arbeitsged\xe4chtnis zu halten und zu bearbeiten. Der klarste Gewinn ist Geschwindigkeit und Genauigkeit beim Rechnen selbst.",history:"Schnelles Kopfrechnen ist eine uralte Fertigkeit, \xfcber Jahrhunderte gelehrt mit dem Abakus und seinem japanischen Nachkommen, dem Soroban, mit der vedischen Mathematik und mit benannten Kurzwegsystemen. Das auf Zeit gesetzte, spielerische Format ist eine moderne Anpassung, die mit Handheld-Spielen und Gehirntraining-Apps in den 2000er Jahren aufkam.",creator:"Es gibt keinen einzelnen Erfinder \u2014 Kopfrechnen auf Zeit ist eine allgemeine \xdcbung, verwurzelt in \xe4lteren Rechentraditionen. Die bekanntesten benannten, systematisierten Methoden sind die Soroban-Praxis (japanischer Abakus) und das Trachtenberg-System, eine Sammlung von Kopfrechen-Kurzwegen, die der Ingenieur Jakow Trachtenberg in den 1940er Jahren ersann; das Schnellrechen-Format selbst geh\xf6rt niemandem.",methods:"Beherrsche deine Kernfakten aus dem Effeff (Additionspaare und Einmaleins), damit der Abruf automatisch l\xe4uft, und lege dann Strategien obendrauf: runden und ausgleichen (98 + 47 als 100 + 47 - 2), Zahlen zerlegen (7 x 13 als 7 x 10 + 7 x 3) und absch\xe4tzen, bevor du rechnest. Trainiere eine Rechenart nach der anderen, bis sie sich leicht anf\xfchlt, und mische sie dann.",duration:"Kurze, h\xe4ufige Sitzungen schlagen Marathons. F\xfcnf bis zehn Minuten am Tag, an den meisten Tagen, bringen dein Tempo schneller voran als eine Stunde einmal pro Woche, denn der Abruf von Fakten festigt sich durch verteiltes Wiederholen.",research:"Die Evidenz ist genau f\xfcr das am st\xe4rksten, was man erwarten w\xfcrde \u2014 \xfcbe Rechnen auf Zeit, und du wirst beim Rechnen schneller und genauer. Die gr\xf6\xdferen Behauptungen sind viel schw\xe4cher: Ein breiter \xdcbertrag auf allgemeine Intelligenz oder das Arbeitsged\xe4chtnis ist weitgehend unbewiesen, und mehrere ber\xfchmte Gehirntraining-Befunde, darunter die Idee, dass Arbeitsged\xe4chtnis\xfcbungen die fluide Intelligenz heben, lie\xdfen sich in kontrollierten Studien nicht replizieren. Begegne Versprechen von einem kl\xfcgeren Gehirn oder verhindertem Abbau mit Vorsicht; der verl\xe4ssliche Ertrag ist die Fertigkeit selbst und, f\xfcr viele Menschen, weniger Angst im Umgang mit Zahlen.",rec:"W\xe4hle eine Rechenart, bei der du langsam bist, \xfcbe sie t\xe4glich f\xfcnf konzentrierte Minuten und mische die anderen erst dann hinzu, wenn sie sich m\xfchelos anf\xfchlt.",faq:[["Macht mich das insgesamt besser in Mathe?","Es macht dich zuverl\xe4ssig schneller und genauer im Kopfrechnen und kann die Zahlenangst lindern. Es bringt dir nicht von allein Algebra oder h\xf6here Mathematik bei, und es gibt kaum belastbare Belege, dass es die allgemeine Intelligenz hebt."],["Ist es Schummeln, Kniffe wie das Runden zu nutzen?","Nein \u2014 runden, Zahlen zerlegen und absch\xe4tzen sind genau die Art, wie sichere Kopfrechner arbeiten. Das Ziel ist die richtige Antwort, und zwar schnell, nicht ein bestimmtes Vorgehen, also sind gute Abk\xfcrzungen die Fertigkeit, kein Trick."],["Wie lange dauert es, bis ich merke, dass ich schneller bin?","Die meisten Menschen sp\xfcren einen Unterschied innerhalb von ein paar Wochen kurzer t\xe4glicher \xdcbung, weil die Grundfakten schnell automatisch werden. Mehr Tempo bei mehrstufigen Aufgaben verbessert sich \xfcber Monate weiter."]],variants:"\xdcbliche Abwandlungen sind Modi mit einer einzelnen Rechenart, Sprints mit gemischten Rechenarten, fester Countdown gegen\xfcber endlosen Serien, ansteigender Schwierigkeitsgrad bei richtigen Antworten und Sch\xe4tzmodi, in denen du die n\xe4chstliegende statt der genauen Antwort w\xe4hlst."},pt:{about:"Mental Math Sprint \xe9 um exerc\xedcio cronometrado de aritm\xe9tica. A tela despeja sobre voc\xea uma sequ\xeancia de problemas simples \u2014 adi\xe7\xe3o, subtra\xe7\xe3o, multiplica\xe7\xe3o, divis\xe3o \u2014 e sua miss\xe3o \xe9 resolver cada um de cabe\xe7a e responder o mais r\xe1pido poss\xedvel antes que o tempo acabe.",benefit:"Desenvolve a flu\xeancia aritm\xe9tica: recupera\xe7\xe3o mais r\xe1pida de fatos, estimativa mais \xe1gil e a capacidade de manter e manipular n\xfameros na mem\xf3ria de trabalho sob press\xe3o de tempo. O ganho mais claro \xe9 a velocidade e a precis\xe3o no pr\xf3prio c\xe1lculo.",history:"O c\xe1lculo mental r\xe1pido \xe9 uma habilidade antiga, ensinada por s\xe9culos pelo \xe1baco e por seu descendente japon\xeas, o soroban, pela matem\xe1tica v\xe9dica e por sistemas de atalho com nome pr\xf3prio. O formato cronometrado e gamificado \xe9 uma adapta\xe7\xe3o moderna que ganhou for\xe7a com os videogames port\xe1teis e os aplicativos de treino cerebral nos anos 2000.",creator:"N\xe3o h\xe1 um \xfanico inventor \u2014 a aritm\xe9tica mental cronometrada \xe9 um exerc\xedcio gen\xe9rico enraizado em tradi\xe7\xf5es de c\xe1lculo mais antigas. Os m\xe9todos sistematizados de maior nome s\xe3o a pr\xe1tica do soroban (\xe1baco japon\xeas) e o sistema Trachtenberg, um conjunto de atalhos de c\xe1lculo mental concebido pelo engenheiro Jakow Trachtenberg na d\xe9cada de 1940; o formato do exerc\xedcio de velocidade em si n\xe3o pertence a ningu\xe9m.",methods:"Memorize seus fatos b\xe1sicos com firmeza (pares de soma e tabuadas) para que a recupera\xe7\xe3o seja autom\xe1tica, e ent\xe3o acrescente estrat\xe9gias: arredonde e ajuste (98 + 47 como 100 + 47 - 2), decomponha os n\xfameros (7 x 13 como 7 x 10 + 7 x 3) e estime antes de calcular. Treine uma opera\xe7\xe3o de cada vez at\xe9 que ela pare\xe7a f\xe1cil, e s\xf3 depois misture-as.",duration:"Sess\xf5es curtas e frequentes batem maratonas. Cinco a dez minutos por dia, na maioria dos dias, aumentam sua velocidade mais r\xe1pido do que uma hora uma vez por semana, porque a recupera\xe7\xe3o de fatos se fortalece pela repeti\xe7\xe3o espa\xe7ada.",research:"A evid\xeancia \xe9 mais forte para exatamente o que se esperaria \u2014 pratique aritm\xe9tica cronometrada e voc\xea fica mais r\xe1pido e mais preciso em aritm\xe9tica. As afirma\xe7\xf5es maiores s\xe3o bem mais fracas: a transfer\xeancia ampla para a intelig\xeancia geral ou a mem\xf3ria de trabalho \xe9 em grande parte n\xe3o comprovada, e v\xe1rios achados famosos de treino cerebral, incluindo a ideia de que exerc\xedcios de mem\xf3ria de trabalho elevam a intelig\xeancia fluida, n\xe3o se replicaram em estudos controlados. Trate promessas de um c\xe9rebro mais inteligente ou de decl\xednio evitado com cautela; o retorno confi\xe1vel \xe9 a pr\xf3pria habilidade mais, para muita gente, menos ansiedade com n\xfameros.",rec:"Escolha uma opera\xe7\xe3o em que voc\xea \xe9 lento, treine-a por cinco minutos focados todos os dias, e s\xf3 misture as outras quando ela parecer sem esfor\xe7o.",faq:[["Isto vai me deixar melhor em matem\xe1tica no geral?","Deixa voc\xea confiavelmente mais r\xe1pido e mais preciso em aritm\xe9tica mental e pode aliviar a ansiedade com n\xfameros. Por si s\xf3 n\xe3o vai ensinar \xe1lgebra ou matem\xe1tica avan\xe7ada, e h\xe1 pouca evid\xeancia s\xf3lida de que eleve a intelig\xeancia geral."],["\xc9 trapa\xe7a usar truques como arredondamento?","N\xe3o \u2014 arredondar, decompor n\xfameros e estimar s\xe3o exatamente como trabalham os calculadores fluentes. O objetivo \xe9 a resposta certa com rapidez, n\xe3o um procedimento espec\xedfico, ent\xe3o bons atalhos s\xe3o a habilidade, n\xe3o um desvio."],["Quanto tempo at\xe9 eu notar que estou mais r\xe1pido?","A maioria das pessoas sente diferen\xe7a em poucas semanas de pr\xe1tica di\xe1ria curta, porque os fatos b\xe1sicos se tornam autom\xe1ticos rapidamente. A velocidade mais profunda em problemas de v\xe1rias etapas continua melhorando ao longo de meses."]],variants:"Varia\xe7\xf5es comuns incluem modos de opera\xe7\xe3o \xfanica, sprints com opera\xe7\xf5es mistas, contagem regressiva fixa versus sequ\xeancias infinitas, dificuldade crescente conforme voc\xea acerta e modos de estimativa em que voc\xea escolhe a resposta mais pr\xf3xima em vez da exata."},hi:{about:"Mental Math Sprint \u0938\u092e\u092f-\u092c\u0926\u094d\u0927 \u0905\u0902\u0915\u0917\u0923\u093f\u0924 \u0915\u0940 \u090f\u0915 \u0915\u0938\u0930\u0924 \u0939\u0948\u0964 \u0938\u094d\u0915\u094d\u0930\u0940\u0928 \u0906\u092a \u092a\u0930 \u0938\u0930\u0932 \u0938\u0935\u093e\u0932\u094b\u0902 \u0915\u0940 \u090f\u0915 \u0927\u093e\u0930\u093e \u092b\u0947\u0902\u0915\u0924\u0940 \u0939\u0948 \u2014 \u091c\u094b\u0921\u093c, \u0918\u091f\u093e\u0935, \u0917\u0941\u0923\u093e, \u092d\u093e\u0917 \u2014 \u0914\u0930 \u0906\u092a\u0915\u093e \u0915\u093e\u092e \u0939\u0948 \u0939\u0930 \u0938\u0935\u093e\u0932 \u092e\u0928 \u0939\u0940 \u092e\u0928 \u0939\u0932 \u0915\u0930\u0915\u0947 \u0918\u0921\u093c\u0940 \u0916\u093c\u0924\u094d\u092e \u0939\u094b\u0928\u0947 \u0938\u0947 \u092a\u0939\u0932\u0947 \u091c\u093f\u0924\u0928\u0940 \u091c\u0932\u094d\u0926\u0940 \u0939\u094b \u0938\u0915\u0947 \u091c\u0935\u093e\u092c \u0926\u0947\u0928\u093e\u0964",benefit:"\u092f\u0939 \u0905\u0902\u0915\u0917\u0923\u093f\u0924\u0940\u092f \u0927\u093e\u0930\u093e\u092a\u094d\u0930\u0935\u093e\u0939\u093f\u0924\u093e (\u092b\u093c\u094d\u0932\u0941\u090f\u0902\u0938\u0940) \u0917\u0922\u093c\u0924\u093e \u0939\u0948: \u0924\u0925\u094d\u092f\u094b\u0902 \u0915\u094b \u0924\u0947\u091c\u093c\u0940 \u0938\u0947 \u092f\u093e\u0926 \u0938\u0947 \u0928\u093f\u0915\u093e\u0932\u0928\u093e, \u092b\u091f\u093e\u092b\u091f \u0905\u0928\u0941\u092e\u093e\u0928 \u0932\u0917\u093e\u0928\u093e, \u0914\u0930 \u0938\u092e\u092f \u0915\u0947 \u0926\u092c\u093e\u0935 \u092e\u0947\u0902 \u0938\u0902\u0916\u094d\u092f\u093e\u0913\u0902 \u0915\u094b \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932 \u0938\u094d\u092e\u0943\u0924\u093f \u092e\u0947\u0902 \u0925\u093e\u092e\u0915\u0930 \u0909\u0928 \u092a\u0930 \u0915\u093e\u092e \u0915\u0930\u0928\u093e\u0964 \u0938\u092c\u0938\u0947 \u0938\u093e\u092b\u093c \u092b\u093c\u093e\u092f\u0926\u093e \u0916\u0941\u0926 \u0917\u0923\u0928\u093e \u092e\u0947\u0902 \u0917\u0924\u093f \u0914\u0930 \u0938\u091f\u0940\u0915\u0924\u093e \u0939\u0948\u0964",history:"\u0924\u0947\u091c\u093c \u092e\u093e\u0928\u0938\u093f\u0915 \u0917\u0923\u0928\u093e \u090f\u0915 \u092a\u094d\u0930\u093e\u091a\u0940\u0928 \u0915\u094c\u0936\u0932 \u0939\u0948, \u091c\u093f\u0938\u0947 \u0938\u0926\u093f\u092f\u094b\u0902 \u0924\u0915 \u0905\u092c\u0947\u0915\u0938 \u0914\u0930 \u0907\u0938\u0915\u0947 \u091c\u093e\u092a\u093e\u0928\u0940 \u0935\u0902\u0936\u091c \u0938\u094b\u0930\u094b\u092c\u0928 \u0915\u0947 \u091c\u093c\u0930\u093f\u090f, \u0935\u0948\u0926\u093f\u0915 \u0917\u0923\u093f\u0924 \u0915\u0947 \u091c\u093c\u0930\u093f\u090f, \u0914\u0930 \u0928\u093e\u092e\u0927\u093e\u0930\u0940 \u0936\u0949\u0930\u094d\u091f\u0915\u091f \u092a\u094d\u0930\u0923\u093e\u0932\u093f\u092f\u094b\u0902 \u0915\u0947 \u091c\u093c\u0930\u093f\u090f \u0938\u093f\u0916\u093e\u092f\u093e \u091c\u093e\u0924\u093e \u0930\u0939\u093e\u0964 \u0938\u092e\u092f-\u092c\u0926\u094d\u0927, \u0916\u0947\u0932-\u0930\u0942\u092a\u0940 \u092b\u093c\u0949\u0930\u094d\u092e\u0947\u091f \u090f\u0915 \u0906\u0927\u0941\u0928\u093f\u0915 \u0930\u0942\u092a\u093e\u0902\u0924\u0930 \u0939\u0948 \u091c\u094b 2000 \u0915\u0947 \u0926\u0936\u0915 \u092e\u0947\u0902 \u0939\u093e\u0925 \u092e\u0947\u0902 \u092a\u0915\u0921\u093c\u0928\u0947 \u0935\u093e\u0932\u0947 \u0917\u0947\u092e \u0914\u0930 \u0926\u093f\u092e\u093e\u0917\u0940 \u0915\u0938\u0930\u0924 \u0935\u093e\u0932\u0947 \u0910\u092a\u094d\u0938 \u0915\u0947 \u0938\u093e\u0925 \u091a\u0932 \u092a\u0921\u093c\u093e\u0964",creator:"\u0907\u0938\u0915\u093e \u0915\u094b\u0908 \u090f\u0915\u092e\u093e\u0924\u094d\u0930 \u0906\u0935\u093f\u0937\u094d\u0915\u093e\u0930\u0915 \u0928\u0939\u0940\u0902 \u0939\u0948 \u2014 \u0938\u092e\u092f-\u092c\u0926\u094d\u0927 \u092e\u093e\u0928\u0938\u093f\u0915 \u0905\u0902\u0915\u0917\u0923\u093f\u0924 \u090f\u0915 \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u0915\u0938\u0930\u0924 \u0939\u0948 \u091c\u093f\u0938\u0915\u0940 \u091c\u0921\u093c\u0947\u0902 \u092a\u0941\u0930\u093e\u0928\u0940 \u0917\u0923\u0928\u093e \u092a\u0930\u0902\u092a\u0930\u093e\u0913\u0902 \u092e\u0947\u0902 \u0939\u0948\u0902\u0964 \u0938\u092c\u0938\u0947 \u092e\u0936\u0939\u0942\u0930 \u0928\u093e\u092e\u0927\u093e\u0930\u0940 \u0935\u094d\u092f\u0935\u0938\u094d\u0925\u093f\u0924 \u092a\u0926\u094d\u0927\u0924\u093f\u092f\u093e\u0901 \u0939\u0948\u0902 \u0938\u094b\u0930\u094b\u092c\u0928 (\u091c\u093e\u092a\u093e\u0928\u0940 \u0905\u092c\u0947\u0915\u0938) \u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0914\u0930 \u091f\u094d\u0930\u0947\u091a\u0947\u0928\u092c\u0930\u094d\u0917 \u092a\u094d\u0930\u0923\u093e\u0932\u0940, \u092f\u093e\u0928\u0940 \u0907\u0902\u091c\u0940\u0928\u093f\u092f\u0930 Jakow Trachtenberg \u0926\u094d\u0935\u093e\u0930\u093e 1940 \u0915\u0947 \u0926\u0936\u0915 \u092e\u0947\u0902 \u0930\u091a\u0947 \u0917\u090f \u092e\u093e\u0928\u0938\u093f\u0915-\u0917\u0923\u0928\u093e \u0915\u0947 \u0936\u0949\u0930\u094d\u091f\u0915\u091f \u0915\u093e \u0938\u092e\u0942\u0939; \u092a\u0930 \u0916\u0941\u0926 \u092f\u0939 \u0924\u0947\u091c\u093c-\u0915\u0938\u0930\u0924 \u0935\u093e\u0932\u093e \u092b\u093c\u0949\u0930\u094d\u092e\u0947\u091f \u0915\u093f\u0938\u0940 \u0915\u093e \u0928\u0939\u0940\u0902\u0964",methods:"\u0905\u092a\u0928\u0947 \u092c\u0941\u0928\u093f\u092f\u093e\u0926\u0940 \u0924\u0925\u094d\u092f\u094b\u0902 \u0915\u094b \u092a\u0915\u094d\u0915\u093e \u0930\u091f \u0932\u0940\u091c\u093f\u090f (\u091c\u094b\u0921\u093c \u0915\u0947 \u091c\u094b\u0921\u093c\u0947 \u0914\u0930 \u092a\u0939\u093e\u0921\u093c\u0947) \u0924\u093e\u0915\u093f \u092f\u093e\u0926 \u0938\u0947 \u0928\u093f\u0915\u093e\u0932\u0928\u093e \u0905\u092a\u0928\u0947-\u0906\u092a \u0939\u094b \u091c\u093e\u090f, \u092b\u093f\u0930 \u0909\u0938 \u092a\u0930 \u0930\u0923\u0928\u0940\u0924\u093f\u092f\u093e\u0901 \u091a\u0922\u093c\u093e\u0907\u090f: \u0917\u094b\u0932 \u0915\u0930\u0915\u0947 \u0938\u092e\u093e\u092f\u094b\u091c\u093f\u0924 \u0915\u0940\u091c\u093f\u090f (98 + 47 \u0915\u094b 100 + 47 - 2 \u0915\u0940 \u0924\u0930\u0939), \u0938\u0902\u0916\u094d\u092f\u093e\u0913\u0902 \u0915\u094b \u0924\u094b\u0921\u093c\u093f\u090f (7 \xd7 13 \u0915\u094b 7 \xd7 10 + 7 \xd7 3 \u0915\u0940 \u0924\u0930\u0939), \u0914\u0930 \u0917\u0923\u0928\u093e \u0938\u0947 \u092a\u0939\u0932\u0947 \u0905\u0928\u0941\u092e\u093e\u0928 \u0932\u0917\u093e\u0907\u090f\u0964 \u090f\u0915 \u092c\u093e\u0930 \u092e\u0947\u0902 \u090f\u0915 \u0938\u0902\u0915\u094d\u0930\u093f\u092f\u093e \u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0940\u091c\u093f\u090f \u091c\u092c \u0924\u0915 \u0935\u0939 \u0906\u0938\u093e\u0928 \u0928 \u0932\u0917\u0928\u0947 \u0932\u0917\u0947, \u092b\u093f\u0930 \u0909\u0928\u094d\u0939\u0947\u0902 \u092e\u093f\u0932\u093e \u0926\u0940\u091c\u093f\u090f\u0964",duration:"\u091b\u094b\u091f\u0947, \u092c\u093e\u0930-\u092c\u093e\u0930 \u0915\u0947 \u0938\u0924\u094d\u0930 \u092e\u0948\u0930\u093e\u0925\u0928 \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u0939\u0948\u0902\u0964 \u0930\u094b\u091c\u093c, \u091c\u093c\u094d\u092f\u093e\u0926\u093e\u0924\u0930 \u0926\u093f\u0928, \u092a\u093e\u0901\u091a \u0938\u0947 \u0926\u0938 \u092e\u093f\u0928\u091f \u0906\u092a\u0915\u0940 \u0917\u0924\u093f \u0915\u094b \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u090f\u0915 \u0918\u0902\u091f\u0947 \u0938\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0924\u0947\u091c\u093c \u092c\u0922\u093c\u093e\u090f\u0901\u0917\u0947, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u0924\u0925\u094d\u092f\u094b\u0902 \u0915\u094b \u092f\u093e\u0926 \u0938\u0947 \u0928\u093f\u0915\u093e\u0932\u0928\u093e \u0905\u0902\u0924\u0930\u093e\u0932 \u0935\u093e\u0932\u0940 \u092a\u0941\u0928\u0930\u093e\u0935\u0943\u0924\u094d\u0924\u093f (\u0938\u094d\u092a\u0947\u0938\u094d\u0921 \u0930\u093f\u092a\u0940\u091f\u093f\u0936\u0928) \u0938\u0947 \u092e\u091c\u093c\u092c\u0942\u0924 \u0939\u094b\u0924\u093e \u0939\u0948\u0964",research:"\u0938\u092c\u0938\u0947 \u092a\u0941\u0916\u093c\u094d\u0924\u093e \u0938\u092c\u0942\u0924 \u0920\u0940\u0915 \u0909\u0938\u0940 \u092c\u093e\u0924 \u0915\u093e \u0939\u0948 \u091c\u093f\u0938\u0915\u0940 \u0906\u092a \u0909\u092e\u094d\u092e\u0940\u0926 \u0915\u0930\u0947\u0902\u0917\u0947 \u2014 \u0938\u092e\u092f-\u092c\u0926\u094d\u0927 \u0905\u0902\u0915\u0917\u0923\u093f\u0924 \u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0940\u091c\u093f\u090f \u0914\u0930 \u0906\u092a \u0905\u0902\u0915\u0917\u0923\u093f\u0924 \u092e\u0947\u0902 \u0924\u0947\u091c\u093c \u0935 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0938\u091f\u0940\u0915 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902\u0964 \u092c\u0921\u093c\u0947 \u0926\u093e\u0935\u0947 \u0915\u0939\u0940\u0902 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0915\u092e\u091c\u093c\u094b\u0930 \u0939\u0948\u0902: \u0906\u092e \u092c\u0941\u0926\u094d\u0927\u093f \u092f\u093e \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932 \u0938\u094d\u092e\u0943\u0924\u093f \u0924\u0915 \u0935\u094d\u092f\u093e\u092a\u0915 \u0939\u0938\u094d\u0924\u093e\u0902\u0924\u0930\u0923 \u0915\u093e\u092b\u093c\u0940 \u0939\u0926 \u0924\u0915 \u0905\u0938\u093e\u092c\u093f\u0924 \u0939\u0948, \u0914\u0930 \u0915\u0908 \u092e\u0936\u0939\u0942\u0930 \u0926\u093f\u092e\u093e\u0917\u0940-\u0915\u0938\u0930\u0924 \u0928\u0924\u0940\u091c\u0947, \u091c\u093f\u0928\u092e\u0947\u0902 \u092f\u0939 \u0935\u093f\u091a\u093e\u0930 \u092d\u0940 \u0936\u093e\u092e\u093f\u0932 \u0939\u0948 \u0915\u093f \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932-\u0938\u094d\u092e\u0943\u0924\u093f \u0915\u0940 \u0915\u0938\u0930\u0924\u0947\u0902 \u0926\u094d\u0930\u0935 \u092c\u0941\u0926\u094d\u0927\u093f (\u092b\u093c\u094d\u0932\u0941\u0907\u0921 \u0907\u0902\u091f\u0947\u0932\u093f\u091c\u0947\u0902\u0938) \u092c\u0922\u093c\u093e\u0924\u0940 \u0939\u0948\u0902, \u0938\u0941\u0928\u093f\u092f\u0902\u0924\u094d\u0930\u093f\u0924 \u0905\u0927\u094d\u092f\u092f\u0928\u094b\u0902 \u092e\u0947\u0902 \u0926\u094b\u0939\u0930\u093e\u090f \u0928\u0939\u0940\u0902 \u091c\u093e \u0938\u0915\u0947\u0964 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0939\u094b\u0936\u093f\u092f\u093e\u0930 \u0926\u093f\u092e\u093e\u0917 \u092f\u093e \u0930\u0941\u0915\u0940 \u0939\u0941\u0908 \u0917\u093f\u0930\u093e\u0935\u091f \u0915\u0947 \u0935\u093e\u0926\u094b\u0902 \u0915\u094b \u0938\u093e\u0935\u0927\u093e\u0928\u0940 \u0938\u0947 \u0932\u0940\u091c\u093f\u090f; \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u092b\u093c\u093e\u092f\u0926\u093e \u0916\u0941\u0926 \u092f\u0939 \u0915\u094c\u0936\u0932 \u0939\u0948 \u0914\u0930, \u0915\u0908 \u0932\u094b\u0917\u094b\u0902 \u0915\u0947 \u0932\u093f\u090f, \u0938\u0902\u0916\u094d\u092f\u093e\u0913\u0902 \u0915\u0947 \u0907\u0930\u094d\u0926-\u0917\u093f\u0930\u094d\u0926 \u0915\u092e \u0918\u092c\u0930\u093e\u0939\u091f\u0964",rec:"\u090f\u0915 \u0910\u0938\u0940 \u0938\u0902\u0915\u094d\u0930\u093f\u092f\u093e \u091a\u0941\u0928\u093f\u090f \u091c\u093f\u0938\u092e\u0947\u0902 \u0906\u092a \u0927\u0940\u092e\u0947 \u0939\u0948\u0902, \u0930\u094b\u091c\u093c \u092a\u093e\u0901\u091a \u0915\u0947\u0902\u0926\u094d\u0930\u093f\u0924 \u092e\u093f\u0928\u091f \u0909\u0938\u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0940\u091c\u093f\u090f, \u0914\u0930 \u092c\u093e\u0915\u0940 \u0915\u094b \u0924\u092d\u0940 \u092e\u093f\u0932\u093e\u0907\u090f \u091c\u092c \u0935\u0939 \u0938\u0939\u091c \u0932\u0917\u0928\u0947 \u0932\u0917\u0947\u0964",faq:[["\u0915\u094d\u092f\u093e \u092f\u0939 \u092e\u0941\u091d\u0947 \u0915\u0941\u0932 \u092e\u093f\u0932\u093e\u0915\u0930 \u0917\u0923\u093f\u0924 \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u092c\u0928\u093e \u0926\u0947\u0917\u093e?","\u092f\u0939 \u0906\u092a\u0915\u094b \u092e\u093e\u0928\u0938\u093f\u0915 \u0905\u0902\u0915\u0917\u0923\u093f\u0924 \u092e\u0947\u0902 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0922\u0902\u0917 \u0938\u0947 \u0924\u0947\u091c\u093c \u0935 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0938\u091f\u0940\u0915 \u092c\u0928\u093e\u0924\u093e \u0939\u0948, \u0914\u0930 \u0938\u0902\u0916\u094d\u092f\u093e\u0913\u0902 \u0915\u0940 \u0918\u092c\u0930\u093e\u0939\u091f \u0915\u092e \u0915\u0930 \u0938\u0915\u0924\u093e \u0939\u0948\u0964 \u092f\u0939 \u0905\u092a\u0928\u0947-\u0906\u092a \u092c\u0940\u091c\u0917\u0923\u093f\u0924 \u092f\u093e \u090a\u0901\u091a\u093e \u0917\u0923\u093f\u0924 \u0928\u0939\u0940\u0902 \u0938\u093f\u0916\u093e\u090f\u0917\u093e, \u0914\u0930 \u0907\u0938\u0915\u093e \u0915\u094b\u0908 \u0916\u093e\u0938 \u092a\u0941\u0916\u093c\u094d\u0924\u093e \u0938\u092c\u0942\u0924 \u0928\u0939\u0940\u0902 \u0915\u093f \u092f\u0939 \u0906\u092e \u092c\u0941\u0926\u094d\u0927\u093f \u092c\u0922\u093c\u093e\u0924\u093e \u0939\u0948\u0964"],["\u0917\u094b\u0932\u093e\u0908 \u092e\u0947\u0902 \u0932\u093e\u0928\u0947 \u091c\u0948\u0938\u0940 \u0924\u0930\u0915\u0940\u092c\u0947\u0902 \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0915\u0930\u0928\u093e \u0915\u094d\u092f\u093e \u092c\u0947\u0908\u092e\u093e\u0928\u0940 \u0939\u0948?","\u0928\u0939\u0940\u0902 \u2014 \u0917\u094b\u0932 \u0915\u0930\u0928\u093e, \u0938\u0902\u0916\u094d\u092f\u093e\u0913\u0902 \u0915\u094b \u0924\u094b\u0921\u093c\u0928\u093e \u0914\u0930 \u0905\u0928\u0941\u092e\u093e\u0928 \u0932\u0917\u093e\u0928\u093e \u0920\u0940\u0915 \u0935\u0939\u0940 \u0939\u0948 \u091c\u0948\u0938\u0947 \u0927\u093e\u0930\u093e\u092a\u094d\u0930\u0935\u093e\u0939 \u0917\u0923\u0915 \u0915\u093e\u092e \u0915\u0930\u0924\u0947 \u0939\u0948\u0902\u0964 \u092e\u0915\u093c\u0938\u0926 \u091c\u0932\u094d\u0926\u0940 \u0938\u0947 \u0938\u0939\u0940 \u091c\u0935\u093e\u092c \u0939\u0948, \u0915\u094b\u0908 \u0916\u093e\u0938 \u092a\u094d\u0930\u0915\u094d\u0930\u093f\u092f\u093e \u0928\u0939\u0940\u0902, \u0907\u0938\u0932\u093f\u090f \u0905\u091a\u094d\u091b\u0947 \u0936\u0949\u0930\u094d\u091f\u0915\u091f \u092f\u0939\u0940 \u0915\u094c\u0936\u0932 \u0939\u0948\u0902, \u0915\u094b\u0908 \u091c\u0941\u0917\u093e\u0921\u093c \u0928\u0939\u0940\u0902\u0964"],["\u092e\u0941\u091d\u0947 \u0924\u0947\u091c\u093c \u0939\u0941\u0906 \u092e\u0939\u0938\u0942\u0938 \u0939\u094b\u0928\u0947 \u092e\u0947\u0902 \u0915\u093f\u0924\u0928\u093e \u0935\u0915\u093c\u094d\u0924 \u0932\u0917\u0947\u0917\u093e?","\u091c\u093c\u094d\u092f\u093e\u0926\u093e\u0924\u0930 \u0932\u094b\u0917 \u0930\u094b\u091c\u093c \u0915\u0947 \u091b\u094b\u091f\u0947 \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0947 \u0915\u0941\u091b \u0939\u0940 \u0939\u092b\u093c\u094d\u0924\u094b\u0902 \u092e\u0947\u0902 \u092b\u093c\u0930\u094d\u0915 \u092e\u0939\u0938\u0942\u0938 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u092c\u0941\u0928\u093f\u092f\u093e\u0926\u0940 \u0924\u0925\u094d\u092f \u091c\u0932\u094d\u0926\u0940 \u0905\u092a\u0928\u0947-\u0906\u092a \u0939\u094b\u0928\u0947 \u0932\u0917\u0924\u0947 \u0939\u0948\u0902\u0964 \u092c\u0939\u0941-\u091a\u0930\u0923\u0940\u092f \u0938\u0935\u093e\u0932\u094b\u0902 \u092a\u0930 \u0917\u0939\u0930\u0940 \u0917\u0924\u093f \u092e\u0939\u0940\u0928\u094b\u0902 \u0924\u0915 \u0938\u0941\u0927\u0930\u0924\u0940 \u0930\u0939\u0924\u0940 \u0939\u0948\u0964"]],variants:"\u0906\u092e \u092c\u0926\u0932\u093e\u0935\u094b\u0902 \u092e\u0947\u0902 \u0936\u093e\u092e\u093f\u0932 \u0939\u0948\u0902 \u090f\u0915\u0932-\u0938\u0902\u0915\u094d\u0930\u093f\u092f\u093e \u0935\u093e\u0932\u0947 \u092e\u094b\u0921, \u092e\u093f\u0936\u094d\u0930\u093f\u0924-\u0938\u0902\u0915\u094d\u0930\u093f\u092f\u093e \u0935\u093e\u0932\u0940 \u0938\u094d\u092a\u094d\u0930\u093f\u0902\u091f, \u0924\u092f \u0909\u0932\u091f\u0940-\u0917\u093f\u0928\u0924\u0940 \u092c\u0928\u093e\u092e \u0905\u0902\u0924\u0939\u0940\u0928 \u0932\u0921\u093c\u0940, \u0938\u0939\u0940 \u091c\u0935\u093e\u092c \u0926\u0947\u0924\u0947 \u091c\u093e\u0928\u0947 \u092a\u0930 \u092c\u0922\u093c\u0924\u0940 \u0915\u0920\u093f\u0928\u093e\u0908, \u0914\u0930 \u0905\u0928\u0941\u092e\u093e\u0928 \u0935\u093e\u0932\u0947 \u092e\u094b\u0921 \u091c\u0939\u093e\u0901 \u0906\u092a \u0920\u0940\u0915 \u091c\u0935\u093e\u092c \u0915\u0947 \u092c\u091c\u093e\u092f \u0938\u092c\u0938\u0947 \u0915\u0930\u0940\u092c\u0940 \u091c\u0935\u093e\u092c \u091a\u0941\u0928\u0924\u0947 \u0939\u0948\u0902\u0964"},zh:{about:"\u300a\u5fc3\u7b97\u51b2\u523a\u300b\u662f\u4e00\u4e2a\u9650\u65f6\u7b97\u672f\u7ec3\u4e60\u3002\u5c4f\u5e55\u4f1a\u4e0d\u65ad\u5411\u4f60\u629b\u51fa\u4e00\u4e32\u7b80\u5355\u7684\u9898\u76ee\u2014\u2014\u52a0\u3001\u51cf\u3001\u4e58\u3001\u9664\u2014\u2014\u4f60\u7684\u4efb\u52a1\u662f\u5728\u8111\u4e2d\u89e3\u51fa\u6bcf\u4e00\u9053\uff0c\u5e76\u5728\u5012\u8ba1\u65f6\u7ed3\u675f\u524d\u5c3d\u53ef\u80fd\u5feb\u5730\u4f5c\u7b54\u3002",benefit:"\u5b83\u57f9\u517b\u7b97\u672f\u7684\u6d41\u7545\u5ea6\uff1a\u66f4\u5feb\u5730\u8c03\u53d6\u6570\u5b57\u4e8b\u5b9e\u3001\u66f4\u8fc5\u901f\u5730\u4f30\u7b97\uff0c\u4ee5\u53ca\u5728\u65f6\u95f4\u538b\u529b\u4e0b\u628a\u6570\u5b57\u4fdd\u6301\u5728\u5de5\u4f5c\u8bb0\u5fc6\u4e2d\u5e76\u52a0\u4ee5\u8fd0\u7b97\u7684\u80fd\u529b\u3002\u6700\u660e\u663e\u7684\u6536\u83b7\u5c31\u662f\u8ba1\u7b97\u672c\u8eab\u7684\u901f\u5ea6\u548c\u51c6\u786e\u7387\u3002",history:"\u5feb\u901f\u5fc3\u7b97\u662f\u4e00\u9879\u53e4\u8001\u7684\u6280\u80fd\uff0c\u51e0\u767e\u5e74\u6765\u901a\u8fc7\u7b97\u76d8\u53ca\u5176\u65e5\u672c\u540e\u88d4\u73e0\u7b97\u3001\u901a\u8fc7\u5420\u9640\u6570\u5b66\uff0c\u4ee5\u53ca\u901a\u8fc7\u5404\u79cd\u4ee5\u4eba\u540d\u547d\u540d\u7684\u901f\u7b97\u4f53\u7cfb\u5f97\u4ee5\u4f20\u6388\u3002\u8fd9\u79cd\u9650\u65f6\u3001\u6e38\u620f\u5316\u7684\u5f62\u5f0f\u5219\u662f\u4e00\u79cd\u73b0\u4ee3\u6539\u9020\uff0c\u968f\u77402000\u5e74\u4ee3\u7684\u638c\u4e0a\u6e38\u620f\u548c\u5065\u8111\u5e94\u7528\u800c\u6d41\u884c\u8d77\u6765\u3002",creator:"\u5b83\u6ca1\u6709\u5355\u4e00\u7684\u53d1\u660e\u8005\u2014\u2014\u9650\u65f6\u5fc3\u7b97\u662f\u4e00\u9879\u624e\u6839\u4e8e\u66f4\u53e4\u8001\u8ba1\u7b97\u4f20\u7edf\u7684\u901a\u7528\u7ec3\u4e60\u3002\u6700\u8457\u540d\u7684\u51e0\u79cd\u4ee5\u4eba\u540d\u547d\u540d\u7684\u7cfb\u7edf\u5316\u65b9\u6cd5\u662f\u73e0\u7b97\uff08\u65e5\u5f0f\u7b97\u76d8\uff09\u7ec3\u4e60\u548c\u7279\u62c9\u4ea8\u4f2f\u683c\u7cfb\u7edf\u2014\u2014\u540e\u8005\u662f\u5de5\u7a0b\u5e08Jakow Trachtenberg\u572820\u4e16\u7eaa40\u5e74\u4ee3\u521b\u7acb\u7684\u4e00\u5957\u5fc3\u7b97\u901f\u7b97\u7a8d\u95e8\uff1b\u800c\u901f\u7ec3\u8fd9\u79cd\u5f62\u5f0f\u672c\u8eab\u5219\u4e0d\u5c5e\u4e8e\u4efb\u4f55\u4eba\u3002",methods:"\u628a\u4f60\u7684\u6838\u5fc3\u6570\u5b57\u4e8b\u5b9e\u80cc\u5f97\u6eda\u74dc\u70c2\u719f\uff08\u52a0\u6cd5\u914d\u5bf9\u548c\u4e58\u6cd5\u8868\uff09\uff0c\u8ba9\u8c03\u53d6\u81ea\u52a8\u5316\uff0c\u7136\u540e\u518d\u53e0\u52a0\u7b56\u7565\uff1a\u53d6\u6574\u518d\u8c03\u6574\uff08\u628a98\uff0b47\u5f53\u6210100\uff0b47\uff0d2\uff09\u3001\u628a\u6570\u5b57\u62c6\u5f00\uff08\u628a7\xd713\u5f53\u62107\xd710\uff0b7\xd73\uff09\u3001\u5728\u8ba1\u7b97\u4e4b\u524d\u5148\u4f30\u7b97\u3002\u4e00\u6b21\u53ea\u8bad\u7ec3\u4e00\u79cd\u8fd0\u7b97\uff0c\u76f4\u5230\u5b83\u53d8\u5f97\u8f7b\u677e\uff0c\u518d\u628a\u5b83\u4eec\u6df7\u5728\u4e00\u8d77\u7ec3\u3002",duration:"\u77ed\u800c\u9891\u7e41\u7684\u7ec3\u4e60\u80dc\u8fc7\u9a6c\u62c9\u677e\u3002\u6bcf\u5929\u4e94\u5230\u5341\u5206\u949f\u3001\u5927\u591a\u6570\u65e5\u5b50\u90fd\u7ec3\uff0c\u4f1a\u6bd4\u6bcf\u5468\u4e00\u6b21\u7ec3\u4e00\u5c0f\u65f6\u66f4\u5feb\u5730\u63d0\u5347\u4f60\u7684\u901f\u5ea6\uff0c\u56e0\u4e3a\u6570\u5b57\u4e8b\u5b9e\u7684\u8c03\u53d6\u8981\u9760\u95f4\u9694\u91cd\u590d\u6765\u5f3a\u5316\u3002",research:"\u8bc1\u636e\u6700\u5f3a\u7684\u6070\u6070\u662f\u4f60\u80fd\u6599\u5230\u7684\u90a3\u90e8\u5206\u2014\u2014\u7ec3\u4e60\u9650\u65f6\u7b97\u672f\uff0c\u4f60\u5728\u7b97\u672f\u4e0a\u5c31\u4f1a\u53d8\u5f97\u66f4\u5feb\u3001\u66f4\u51c6\u3002\u66f4\u5927\u7684\u90a3\u4e9b\u8bf4\u6cd5\u5219\u8981\u5f31\u5f97\u591a\uff1a\u80fd\u5426\u5e7f\u6cdb\u8fc1\u79fb\u5230\u4e00\u822c\u667a\u529b\u6216\u5de5\u4f5c\u8bb0\u5fc6\uff0c\u57fa\u672c\u4e0a\u672a\u5f97\u5230\u8bc1\u5b9e\uff1b\u51e0\u9879\u8457\u540d\u7684\u5065\u8111\u8bad\u7ec3\u53d1\u73b0\uff0c\u5305\u62ec\u300e\u5de5\u4f5c\u8bb0\u5fc6\u7ec3\u4e60\u80fd\u63d0\u5347\u6d41\u4f53\u667a\u529b\u300f\u8fd9\u4e00\u89c2\u70b9\uff0c\u5728\u5bf9\u7167\u7814\u7a76\u4e2d\u90fd\u672a\u80fd\u590d\u73b0\u3002\u5bf9\u300e\u8ba9\u5927\u8111\u66f4\u806a\u660e\u300f\u6216\u300e\u9884\u9632\u8870\u9000\u300f\u4e4b\u7c7b\u7684\u627f\u8bfa\u8981\u4fdd\u6301\u8c28\u614e\uff1b\u53ef\u9760\u7684\u56de\u62a5\u662f\u6280\u80fd\u672c\u8eab\uff0c\u5916\u52a0\u5bf9\u8bb8\u591a\u4eba\u800c\u8a00\uff0c\u5bf9\u6570\u5b57\u5c11\u4e86\u51e0\u5206\u7126\u8651\u3002",rec:"\u6311\u4e00\u4e2a\u4f60\u7b97\u5f97\u6162\u7684\u8fd0\u7b97\uff0c\u6bcf\u5929\u4e13\u6ce8\u5730\u7ec3\u4e0a\u4e94\u5206\u949f\uff0c\u7b49\u5b83\u53d8\u5f97\u6beb\u4e0d\u8d39\u529b\u4e4b\u540e\uff0c\u518d\u628a\u5176\u5b83\u8fd0\u7b97\u6df7\u8fdb\u6765\u3002",faq:[["\u8fd9\u4f1a\u8ba9\u6211\u6574\u4f53\u4e0a\u66f4\u64c5\u957f\u6570\u5b66\u5417\uff1f","\u5b83\u4e00\u5b9a\u4f1a\u8ba9\u4f60\u5728\u5fc3\u7b97\u4e0a\u53d8\u5f97\u66f4\u5feb\u3001\u66f4\u51c6\uff0c\u4e5f\u80fd\u7f13\u89e3\u5bf9\u6570\u5b57\u7684\u7126\u8651\u3002\u4f46\u5b83\u672c\u8eab\u5e76\u4e0d\u4f1a\u6559\u4f60\u4ee3\u6570\u6216\u66f4\u9ad8\u7b49\u7684\u6570\u5b66\uff0c\u800c\u4e14\u51e0\u4e4e\u6ca1\u6709\u624e\u5b9e\u7684\u8bc1\u636e\u8868\u660e\u5b83\u80fd\u63d0\u5347\u4e00\u822c\u667a\u529b\u3002"],["\u7528\u53d6\u6574\u4e4b\u7c7b\u7684\u7a8d\u95e8\u7b97\u4f5c\u5f0a\u5417\uff1f","\u4e0d\u7b97\u2014\u2014\u53d6\u6574\u3001\u628a\u6570\u5b57\u62c6\u5f00\u548c\u4f30\u7b97\uff0c\u6b63\u662f\u6d41\u7545\u5fc3\u7b97\u8005\u7684\u505a\u6cd5\u3002\u76ee\u6807\u662f\u5feb\u901f\u5f97\u51fa\u6b63\u786e\u7b54\u6848\uff0c\u800c\u4e0d\u662f\u67d0\u4e00\u5957\u7279\u5b9a\u6d41\u7a0b\uff0c\u6240\u4ee5\u597d\u7684\u901f\u7b97\u7a8d\u95e8\u672c\u8eab\u5c31\u662f\u6280\u80fd\uff0c\u800c\u4e0d\u662f\u6295\u673a\u53d6\u5de7\u3002"],["\u8981\u591a\u4e45\u6211\u624d\u80fd\u5bdf\u89c9\u81ea\u5df1\u53d8\u5feb\u4e86\uff1f","\u5927\u591a\u6570\u4eba\u5728\u6bcf\u5929\u77ed\u65f6\u7ec3\u4e60\u51e0\u5468\u4e4b\u540e\u5c31\u80fd\u611f\u5230\u5dee\u522b\uff0c\u56e0\u4e3a\u57fa\u672c\u7684\u6570\u5b57\u4e8b\u5b9e\u5f88\u5feb\u5c31\u4f1a\u53d8\u5f97\u81ea\u52a8\u5316\u3002\u800c\u591a\u6b65\u9aa4\u9898\u76ee\u4e0a\u66f4\u6df1\u5c42\u7684\u901f\u5ea6\u63d0\u5347\uff0c\u5219\u4f1a\u5728\u6570\u6708\u91cc\u6301\u7eed\u6539\u5584\u3002"]],variants:"\u5e38\u89c1\u7684\u53d8\u4f53\u5305\u62ec\u5355\u4e00\u8fd0\u7b97\u6a21\u5f0f\u3001\u6df7\u5408\u8fd0\u7b97\u51b2\u523a\u3001\u56fa\u5b9a\u5012\u8ba1\u65f6\u5bf9\u6bd4\u65e0\u5c3d\u8fde\u51fb\u3001\u968f\u7740\u7b54\u5bf9\u800c\u9010\u7ea7\u63d0\u5347\u96be\u5ea6\uff0c\u4ee5\u53ca\u4f30\u7b97\u6a21\u5f0f\u2014\u2014\u4f60\u6311\u51fa\u6700\u63a5\u8fd1\u7684\u7b54\u6848\uff0c\u800c\u4e0d\u662f\u7cbe\u786e\u7b54\u6848\u3002"}},"memory-matrix":{ru:{about:"\u0412 Memory Matrix \u043d\u0430 \u0441\u0435\u0442\u043a\u0435 \u043d\u0430 \u043c\u0433\u043d\u043e\u0432\u0435\u043d\u0438\u0435 \u0437\u0430\u0433\u043e\u0440\u0430\u044e\u0442\u0441\u044f \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u043a\u043b\u0435\u0442\u043e\u043a, \u0430 \u043f\u043e\u0442\u043e\u043c \u0433\u0430\u0441\u043d\u0443\u0442. \u041d\u0443\u0436\u043d\u043e \u043f\u043e \u043f\u0430\u043c\u044f\u0442\u0438 \u043f\u043e\u0432\u0442\u043e\u0440\u0438\u0442\u044c \u0443\u0437\u043e\u0440, \u043d\u0430\u0436\u0430\u0432 \u0440\u043e\u0432\u043d\u043e \u0442\u0435 \u043a\u043b\u0435\u0442\u043a\u0438, \u0447\u0442\u043e \u0441\u0432\u0435\u0442\u0438\u043b\u0438\u0441\u044c. \u0421 \u043a\u0430\u0436\u0434\u044b\u043c \u0440\u0430\u0437\u043e\u043c \u0441\u0435\u0442\u043a\u0430 \u0440\u0430\u0441\u0442\u0451\u0442, \u0430 \u0443\u0437\u043e\u0440\u044b \u0441\u0442\u0430\u043d\u043e\u0432\u044f\u0442\u0441\u044f \u043f\u043b\u043e\u0442\u043d\u0435\u0435, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0442\u044c \u0432 \u0433\u043e\u043b\u043e\u0432\u0435 \u043f\u0440\u0438\u0445\u043e\u0434\u0438\u0442\u0441\u044f \u0432\u0441\u0451 \u0431\u043e\u043b\u044c\u0448\u0435 \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0439 \u0438\u043d\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u0438 \u0441\u0440\u0430\u0437\u0443.",benefit:"\u0422\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u043e-\u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u0443\u044e \u0440\u0430\u0431\u043e\u0447\u0443\u044e \u043f\u0430\u043c\u044f\u0442\u044c \u0438 \u043a\u0440\u0430\u0442\u043a\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u043e\u0435 \u0437\u0430\u043f\u043e\u043c\u0438\u043d\u0430\u043d\u0438\u0435 \u0440\u0430\u0441\u043f\u043e\u043b\u043e\u0436\u0435\u043d\u0438\u044f, \u0441\u043f\u043e\u0441\u043e\u0431\u043d\u043e\u0441\u0442\u044c \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0441\u0435\u043a\u0443\u043d\u0434 \u0434\u0435\u0440\u0436\u0430\u0442\u044c \u0432 \u0443\u043c\u0435, \u0433\u0434\u0435 \u0438\u043c\u0435\u043d\u043d\u043e \u043d\u0430\u0445\u043e\u0434\u0438\u043b\u0438\u0441\u044c \u043e\u0431\u044a\u0435\u043a\u0442\u044b. \u0421\u0438\u043b\u044c\u043d\u043e \u0437\u0430\u0434\u0435\u0439\u0441\u0442\u0432\u0443\u0435\u0442\u0441\u044f \u0438 \u043a\u043e\u043d\u0446\u0435\u043d\u0442\u0440\u0430\u0446\u0438\u044f: \u043e\u0434\u043d\u0430 \u043e\u043f\u043b\u043e\u0448\u043d\u043e\u0441\u0442\u044c, \u043f\u043e\u043a\u0430 \u0443\u0437\u043e\u0440 \u043c\u0435\u043b\u044c\u043a\u0430\u0435\u0442, \u0438 \u0432\u0435\u0441\u044c \u0440\u0430\u0443\u043d\u0434 \u043f\u043e\u0442\u0435\u0440\u044f\u043d.",history:"\u0423\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u0435 \u044d\u0442\u043e \u0446\u0438\u0444\u0440\u043e\u0432\u043e\u0439 \u043f\u043e\u0442\u043e\u043c\u043e\u043a \u043a\u043b\u0430\u0441\u0441\u0438\u0447\u0435\u0441\u043a\u0438\u0445 \u0442\u0435\u0441\u0442\u043e\u0432 \u043d\u0430 \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0439 \u043e\u0431\u044a\u0451\u043c \u043f\u0430\u043c\u044f\u0442\u0438 \u0438\u0437 \u043d\u0435\u0439\u0440\u043e\u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u0438. \u0424\u043e\u0440\u043c\u0430\u0442 \u0441 \u0441\u0435\u0442\u043a\u043e\u0439 \u0438 \u0432\u0441\u043f\u044b\u0448\u043a\u0430\u043c\u0438 \u0432\u044b\u0448\u0435\u043b \u0432 \u043c\u0430\u0441\u0441\u044b \u0431\u043b\u0430\u0433\u043e\u0434\u0430\u0440\u044f \u043f\u0440\u0438\u043b\u043e\u0436\u0435\u043d\u0438\u044f\u043c \u0434\u043b\u044f \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0438 \u043c\u043e\u0437\u0433\u0430 \u0432 \u043a\u043e\u043d\u0446\u0435 2000-\u0445 \u0438 \u0432 2010-\u0445; \u0441\u0430\u043c\u0430\u044f \u0438\u0437\u0432\u0435\u0441\u0442\u043d\u0430\u044f \u0432\u0435\u0440\u0441\u0438\u044f \u0438 \u0438\u0441\u0442\u043e\u0447\u043d\u0438\u043a \u043d\u0430\u0437\u0432\u0430\u043d\u0438\u044f Memory Matrix \u043e\u0442 Lumosity.",creator:"\u0415\u0434\u0438\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0433\u043e \u0438\u0437\u043e\u0431\u0440\u0435\u0442\u0430\u0442\u0435\u043b\u044f \u043d\u0435\u0442. \u0424\u043e\u0440\u043c\u0430\u0442 \u043d\u0430\u043f\u0440\u044f\u043c\u0443\u044e \u0432\u044b\u0440\u043e\u0441 \u0438\u0437 \u0442\u0435\u0441\u0442\u0430 \u041a\u043e\u0440\u0441\u0438 \u0441 \u043f\u043e\u0441\u0442\u0443\u043a\u0438\u0432\u0430\u043d\u0438\u0435\u043c \u043f\u043e \u043a\u0443\u0431\u0438\u043a\u0430\u043c, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u043a\u0430\u043d\u0430\u0434\u0441\u043a\u043e-\u0438\u0442\u0430\u043b\u044c\u044f\u043d\u0441\u043a\u0438\u0439 \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433 \u0424\u0438\u043b\u0438\u043f \u041a\u043e\u0440\u0441\u0438 \u043f\u0440\u0438\u0434\u0443\u043c\u0430\u043b \u043f\u0440\u0438\u043c\u0435\u0440\u043d\u043e \u0432 1972 - 1973 \u0433\u043e\u0434\u0430\u0445 \u043a\u0430\u043a \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0439 \u0430\u043d\u0430\u043b\u043e\u0433 \u0437\u0430\u043f\u043e\u043c\u0438\u043d\u0430\u043d\u0438\u044f \u0440\u044f\u0434\u0430 \u0446\u0438\u0444\u0440 \u0438 \u043f\u0440\u043e\u0434\u043e\u043b\u0436\u0435\u043d\u0438\u0435 \u0431\u043e\u043b\u0435\u0435 \u0440\u0430\u043d\u043d\u0438\u0445 \u0440\u0430\u0431\u043e\u0442 \u0414. \u041e. \u0425\u0435\u0431\u0431\u0430. \u041f\u0440\u0438\u0432\u044b\u0447\u043d\u0443\u044e \u0436\u0435 \u043e\u0442\u043f\u043e\u043b\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u0443\u044e \u0438\u0433\u0440\u0443 \u043d\u0430 \u0441\u0435\u0442\u043a\u0435 \u0441\u043e\u0431\u0440\u0430\u043b\u0430 \u0438 \u043d\u0430\u0437\u0432\u0430\u043b\u0430 Memory Matrix \u043a\u043e\u043c\u043f\u0430\u043d\u0438\u044f Lumos Labs (Lumosity).",methods:"\u041d\u0435 \u0437\u0430\u0443\u0447\u0438\u0432\u0430\u0439\u0442\u0435 \u043a\u043b\u0435\u0442\u043a\u0438 \u043f\u043e \u043e\u0434\u043d\u043e\u0439. \u0421\u0432\u043e\u0440\u0430\u0447\u0438\u0432\u0430\u0439\u0442\u0435 \u0437\u0430\u0433\u043e\u0440\u0435\u0432\u0448\u0438\u0435\u0441\u044f \u043a\u043b\u0435\u0442\u043a\u0438 \u0432 \u0444\u0438\u0433\u0443\u0440\u044b, \u043b\u0438\u043d\u0438\u0438 \u0438 \u0433\u0440\u0443\u043f\u043f\u044b, \u0437\u0430\u043c\u0435\u0447\u0430\u0439\u0442\u0435 \u0434\u0438\u0430\u0433\u043e\u043d\u0430\u043b\u0438 \u0438 \u0441\u0438\u043c\u043c\u0435\u0442\u0440\u0438\u044e. \u0414\u0435\u0440\u0436\u0438\u0442\u0435 \u0432\u0437\u0433\u043b\u044f\u0434 \u0431\u043b\u0438\u0436\u0435 \u043a \u0446\u0435\u043d\u0442\u0440\u0443, \u0447\u0442\u043e\u0431\u044b \u0432\u0438\u0434\u0435\u0442\u044c \u0432\u0441\u0451 \u043f\u043e\u043b\u0435 \u0446\u0435\u043b\u0438\u043a\u043e\u043c, \u0438 \u043f\u0440\u043e \u0441\u0435\u0431\u044f \u043e\u0442\u043c\u0435\u0447\u0430\u0439\u0442\u0435 \u0433\u0440\u0443\u0431\u044b\u0435 \u043e\u0440\u0438\u0435\u043d\u0442\u0438\u0440\u044b (\u043b\u0435\u0432\u044b\u0439 \u0432\u0435\u0440\u0445\u043d\u0438\u0439 \u0443\u0433\u043e\u043b, \u0441\u0440\u0435\u0434\u043d\u0438\u0439 \u0440\u044f\u0434), \u0430 \u043d\u0435 \u043f\u0435\u0440\u0435\u0441\u0447\u0438\u0442\u044b\u0432\u0430\u0439\u0442\u0435 \u043a\u0432\u0430\u0434\u0440\u0430\u0442\u044b. \u041f\u043e\u0434\u043d\u0438\u043c\u0430\u0439\u0442\u0435 \u0441\u043b\u043e\u0436\u043d\u043e\u0441\u0442\u044c \u0434\u043e \u0443\u0440\u043e\u0432\u043d\u044f, \u043d\u0430 \u043a\u043e\u0442\u043e\u0440\u043e\u043c \u043e\u0448\u0438\u0431\u0430\u0435\u0442\u0435\u0441\u044c \u043f\u0440\u0438\u043c\u0435\u0440\u043d\u043e \u0432 \u0442\u0440\u0435\u0442\u0438 \u0440\u0430\u0443\u043d\u0434\u043e\u0432: \u0438\u043c\u0435\u043d\u043d\u043e \u043d\u0430 \u044d\u0442\u043e\u0439 \u0433\u0440\u0430\u043d\u0438 \u043e\u0431\u044a\u0451\u043c \u043f\u0430\u043c\u044f\u0442\u0438 \u0440\u0435\u0430\u043b\u044c\u043d\u043e \u0440\u0430\u0441\u0442\u044f\u0433\u0438\u0432\u0430\u0435\u0442\u0441\u044f.",duration:"\u041b\u0443\u0447\u0448\u0435 \u0440\u0430\u0431\u043e\u0442\u0430\u044e\u0442 \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u0435 \u043f\u043e\u0434\u0445\u043e\u0434\u044b: \u043f\u044f\u0442\u044c-\u0434\u0435\u0441\u044f\u0442\u044c \u043c\u0438\u043d\u0443\u0442 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0440\u0430\u0437 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e \u0441 \u043f\u043e\u043b\u043d\u043e\u0439 \u0432\u043a\u043b\u044e\u0447\u0451\u043d\u043d\u043e\u0441\u0442\u044c\u044e \u044d\u0444\u0444\u0435\u043a\u0442\u0438\u0432\u043d\u0435\u0435 \u0434\u043e\u043b\u0433\u0438\u0445 \u043c\u0430\u0440\u0430\u0444\u043e\u043d\u043e\u0432. \u041f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u0430\u044f \u043f\u0430\u043c\u044f\u0442\u044c \u0443\u0441\u0442\u0430\u0451\u0442 \u0431\u044b\u0441\u0442\u0440\u043e, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u043e\u0441\u0442\u0430\u043d\u0430\u0432\u043b\u0438\u0432\u0430\u0439\u0442\u0435\u0441\u044c, \u043a\u0430\u043a \u0442\u043e\u043b\u044c\u043a\u043e \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u044c \u0437\u0430\u043c\u0435\u0442\u043d\u043e \u043f\u0430\u0434\u0430\u0435\u0442, \u0430 \u043d\u0435 \u043f\u0440\u043e\u0434\u0430\u0432\u043b\u0438\u0432\u0430\u0439\u0442\u0435 \u0441\u0435\u0431\u044f \u0447\u0435\u0440\u0435\u0437 \u0443\u0442\u043e\u043c\u043b\u0435\u043d\u0438\u0435.",research:"\u0414\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u043d\u0435\u0435 \u0432\u0441\u0435\u0433\u043e \u0440\u043e\u0432\u043d\u043e \u0442\u043e, \u0447\u0435\u0433\u043e \u0438 \u0436\u0434\u0451\u0448\u044c: \u0432\u044b \u043d\u0430\u0447\u0438\u043d\u0430\u0435\u0442\u0435 \u043b\u0443\u0447\u0448\u0435 \u0437\u0430\u043f\u043e\u043c\u0438\u043d\u0430\u0442\u044c \u0443\u0437\u043e\u0440\u044b \u043d\u0430 \u0441\u0435\u0442\u043a\u0435 \u0438 \u0441\u0445\u043e\u0436\u0438\u0435 \u0437\u0430\u0434\u0430\u0447\u0438 \u043d\u0430 \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0439 \u043e\u0431\u044a\u0451\u043c. \u0411\u043e\u043b\u0435\u0435 \u0448\u0438\u0440\u043e\u043a\u0438\u0435 \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f \u043a\u0443\u0434\u0430 \u0441\u043b\u0430\u0431\u0435\u0435: \u043c\u0435\u0442\u0430-\u0430\u043d\u0430\u043b\u0438\u0437\u044b \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0438 \u0440\u0430\u0431\u043e\u0447\u0435\u0439 \u043f\u0430\u043c\u044f\u0442\u0438, \u0432\u043a\u043b\u044e\u0447\u0430\u044f \u0438\u0437\u0432\u0435\u0441\u0442\u043d\u044b\u0439 \u043e\u0431\u0437\u043e\u0440 \u041c\u0435\u043b\u0431\u0438-\u041b\u0435\u0440\u0432\u0430\u0433 \u0438 \u0425\u044c\u044e\u043c\u0430 2016 \u0433\u043e\u0434\u0430, \u043f\u043e\u0447\u0442\u0438 \u043d\u0435 \u043d\u0430\u0445\u043e\u0434\u044f\u0442 \u043d\u0430\u0434\u0451\u0436\u043d\u043e\u0433\u043e \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0430 \u043d\u0430 \u043e\u0431\u0449\u0438\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442, \u0443\u0441\u043f\u0435\u0432\u0430\u0435\u043c\u043e\u0441\u0442\u044c \u0438\u043b\u0438 \u043f\u043e\u0432\u0441\u0435\u0434\u043d\u0435\u0432\u043d\u0443\u044e \u043f\u0430\u043c\u044f\u0442\u044c. \u0421\u0430\u043c\u0430 Lumosity \u0432 2016 \u0433\u043e\u0434\u0443 \u0432\u044b\u043f\u043b\u0430\u0442\u0438\u043b\u0430 2 \u043c\u0438\u043b\u043b\u0438\u043e\u043d\u0430 \u0434\u043e\u043b\u043b\u0430\u0440\u043e\u0432 \u043f\u043e \u0441\u043e\u0433\u043b\u0430\u0448\u0435\u043d\u0438\u044e \u0441 \u0424\u0435\u0434\u0435\u0440\u0430\u043b\u044c\u043d\u043e\u0439 \u0442\u043e\u0440\u0433\u043e\u0432\u043e\u0439 \u043a\u043e\u043c\u0438\u0441\u0441\u0438\u0435\u0439 \u0421\u0428\u0410 \u0438\u0437-\u0437\u0430 \u043d\u0435\u043e\u0431\u043e\u0441\u043d\u043e\u0432\u0430\u043d\u043d\u044b\u0445 \u0437\u0430\u044f\u0432\u043b\u0435\u043d\u0438\u0439 \u043e \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0435 \u043c\u043e\u0437\u0433\u0430, \u0442\u0430\u043a \u0447\u0442\u043e \u043a \u043f\u043e\u0441\u0443\u043b\u0430\u043c \u043f\u043e\u0434\u043d\u044f\u0442\u044c IQ \u0438\u043b\u0438 \u043e\u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u044c \u0443\u0433\u0430\u0441\u0430\u043d\u0438\u0435 \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u0435\u0441\u044c \u0441 \u043d\u0430\u0441\u0442\u043e\u044f\u0449\u0435\u0439 \u043e\u0441\u0442\u043e\u0440\u043e\u0436\u043d\u043e\u0441\u0442\u044c\u044e.",rec:"\u0418\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0439\u0442\u0435 \u043a\u0430\u043a \u0442\u043e\u0447\u0435\u0447\u043d\u0443\u044e \u0440\u0430\u0437\u043c\u0438\u043d\u043a\u0443 \u0434\u043b\u044f \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0433\u043e \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f, \u0430 \u043d\u0435 \u043a\u0430\u043a \u043b\u0435\u043a\u0430\u0440\u0441\u0442\u0432\u043e \u043e\u0442 \u0437\u0430\u0431\u044b\u0432\u0447\u0438\u0432\u043e\u0441\u0442\u0438, \u0438 \u043e\u0446\u0435\u043d\u0438\u0432\u0430\u0439\u0442\u0435 \u043f\u0440\u043e\u0433\u0440\u0435\u0441\u0441 \u043f\u043e \u0442\u043e\u043c\u0443, \u043a\u0430\u043a \u0440\u0430\u0441\u0442\u0451\u0442 \u0432\u0430\u0448 \u0441\u043e\u0431\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0439 \u043e\u0431\u044a\u0451\u043c \u043f\u0430\u043c\u044f\u0442\u0438 \u0437\u0430 \u043d\u0435\u0434\u0435\u043b\u0438, \u0430 \u043d\u0435 \u043f\u043e \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f\u043c \u0443\u043c\u043d\u043e\u0439 \u0436\u0438\u0437\u043d\u0438.",faq:[["\u0423\u043b\u0443\u0447\u0448\u0438\u0442 \u043b\u0438 Memory Matrix \u043c\u043e\u044e \u043f\u0430\u043c\u044f\u0442\u044c \u0432 \u0440\u0435\u0430\u043b\u044c\u043d\u043e\u0439 \u0436\u0438\u0437\u043d\u0438?","\u041e\u043d \u043d\u0430\u0434\u0451\u0436\u043d\u043e \u043f\u043e\u0432\u044b\u0448\u0430\u0435\u0442 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442 \u0438\u043c\u0435\u043d\u043d\u043e \u0432 \u044d\u0442\u043e\u0439 \u0438 \u043f\u043e\u0445\u043e\u0436\u0438\u0445 \u0437\u0430\u0434\u0430\u0447\u0430\u0445 \u043d\u0430 \u0441\u0435\u0442\u043a\u0435, \u043d\u043e \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u044f \u043d\u0435 \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u044e\u0442 \u0448\u0438\u0440\u043e\u043a\u043e\u0433\u043e \u0432\u044b\u0438\u0433\u0440\u044b\u0448\u0430 \u0432 \u043f\u043e\u0432\u0441\u0435\u0434\u043d\u0435\u0432\u043d\u043e\u0439 \u043f\u0430\u043c\u044f\u0442\u0438 \u0438\u043b\u0438 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442\u0435. \u0421\u0447\u0438\u0442\u0430\u0439\u0442\u0435 \u044d\u0442\u043e \u0430\u0434\u0440\u0435\u0441\u043d\u043e\u0439 \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u043e\u0439 \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0433\u043e \u0437\u0430\u043f\u043e\u043c\u0438\u043d\u0430\u043d\u0438\u044f, \u0430 \u043d\u0435 \u043e\u0431\u0449\u0438\u043c \u0430\u043f\u0433\u0440\u0435\u0439\u0434\u043e\u043c."],["\u0427\u0435\u043c \u044d\u0442\u043e \u043e\u0442\u043b\u0438\u0447\u0430\u0435\u0442\u0441\u044f \u043e\u0442 \u043e\u0431\u044b\u0447\u043d\u043e\u0439 \u0438\u0433\u0440\u044b \u0432 \u043f\u0430\u0440\u043d\u044b\u0435 \u043a\u0430\u0440\u0442\u043e\u0447\u043a\u0438?","\u0412 \u0438\u0433\u0440\u0430\u0445 \u043d\u0430 \u043f\u0430\u0440\u044b (\u0432\u0440\u043e\u0434\u0435 Memory) \u0432\u044b \u043c\u0435\u0442\u043e\u0434\u043e\u043c \u043f\u0440\u043e\u0431 \u0438 \u043e\u0448\u0438\u0431\u043e\u043a \u0437\u0430 \u043c\u043d\u043e\u0433\u043e \u043e\u0442\u043a\u0440\u044b\u0442\u0438\u0439 \u0432\u044b\u044f\u0441\u043d\u044f\u0435\u0442\u0435, \u0433\u0434\u0435 \u043a\u0430\u043a\u043e\u0439 \u0441\u0438\u043c\u0432\u043e\u043b. Memory Matrix \u043f\u043e\u043a\u0430\u0437\u044b\u0432\u0430\u0435\u0442 \u0432\u0435\u0441\u044c \u0443\u0437\u043e\u0440 \u043e\u0434\u0438\u043d \u0440\u0430\u0437, \u0430 \u043f\u043e\u0442\u043e\u043c \u043f\u0440\u043e\u0441\u0438\u0442 \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u0435\u0441\u0442\u0438 \u0442\u043e\u0447\u043d\u044b\u0435 \u043f\u043e\u0437\u0438\u0446\u0438\u0438 \u0441 \u043e\u0434\u043d\u043e\u0433\u043e \u043a\u043e\u0440\u043e\u0442\u043a\u043e\u0433\u043e \u0432\u0437\u0433\u043b\u044f\u0434\u0430, \u0447\u0442\u043e \u043d\u0430\u043f\u0440\u044f\u043c\u0443\u044e \u043d\u0430\u0433\u0440\u0443\u0436\u0430\u0435\u0442 \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u043e-\u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u0443\u044e \u0440\u0430\u0431\u043e\u0447\u0443\u044e \u043f\u0430\u043c\u044f\u0442\u044c."],["\u041a\u0430\u043a \u043d\u0430\u0431\u0440\u0430\u0442\u044c \u0431\u043e\u043b\u044c\u0448\u0435 \u043e\u0447\u043a\u043e\u0432?","\u0413\u0440\u0443\u043f\u043f\u0438\u0440\u0443\u0439\u0442\u0435 \u0437\u0430\u0433\u043e\u0440\u0435\u0432\u0448\u0438\u0435\u0441\u044f \u043a\u043b\u0435\u0442\u043a\u0438 \u0432 \u0444\u0438\u0433\u0443\u0440\u044b \u0438 \u043b\u0438\u043d\u0438\u0438 \u0432\u043c\u0435\u0441\u0442\u043e \u0437\u0430\u0443\u0447\u0438\u0432\u0430\u043d\u0438\u044f \u043e\u0442\u0434\u0435\u043b\u044c\u043d\u044b\u0445 \u043a\u0432\u0430\u0434\u0440\u0430\u0442\u043e\u0432, \u0434\u0435\u0440\u0436\u0438\u0442\u0435 \u0432\u0437\u0433\u043b\u044f\u0434 \u0443 \u0446\u0435\u043d\u0442\u0440\u0430, \u0447\u0442\u043e\u0431\u044b \u043e\u0445\u0432\u0430\u0442\u0438\u0442\u044c \u0432\u0441\u044e \u0441\u0435\u0442\u043a\u0443, \u0438 \u043e\u0441\u0442\u0430\u0432\u0430\u0439\u0442\u0435\u0441\u044c \u043d\u0430 \u0441\u043b\u043e\u0436\u043d\u043e\u0441\u0442\u0438, \u0433\u0434\u0435 \u043e\u0448\u0438\u0431\u0430\u0435\u0442\u0435\u0441\u044c \u0434\u043e\u0441\u0442\u0430\u0442\u043e\u0447\u043d\u043e \u0447\u0430\u0441\u0442\u043e. \u0421\u043b\u0438\u0448\u043a\u043e\u043c \u043b\u0451\u0433\u043a\u0438\u0435 \u0440\u0430\u0443\u043d\u0434\u044b \u043f\u043e\u0447\u0442\u0438 \u043d\u0438\u0447\u0435\u0433\u043e \u043d\u0435 \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u044e\u0442."]],variants:"\u0427\u0430\u0441\u0442\u044b\u0435 \u0432\u0430\u0440\u0438\u0430\u0446\u0438\u0438 \u043c\u0435\u043d\u044f\u044e\u0442 \u0440\u0430\u0437\u043c\u0435\u0440 \u0441\u0435\u0442\u043a\u0438 (\u043e\u0442 \u043c\u0430\u043b\u0435\u043d\u044c\u043a\u043e\u0439 3x3 \u0434\u043e \u043a\u0440\u0443\u043f\u043d\u044b\u0445 \u043f\u043e\u043b\u0435\u0439), \u043f\u043e\u043a\u0430\u0437\u044b\u0432\u0430\u044e\u0442 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0443\u0437\u043e\u0440\u043e\u0432 \u043f\u043e\u0434\u0440\u044f\u0434, \u043f\u0440\u043e\u0441\u044f\u0442 \u043f\u043e\u0432\u0442\u043e\u0440\u0438\u0442\u044c \u043f\u043e\u0440\u044f\u0434\u043e\u043a, \u0432 \u043a\u043e\u0442\u043e\u0440\u043e\u043c \u0437\u0430\u0433\u043e\u0440\u0430\u043b\u0438\u0441\u044c \u043a\u043b\u0435\u0442\u043a\u0438, \u0430 \u043d\u0435 \u043f\u0440\u043e\u0441\u0442\u043e \u0438\u0445 \u043d\u0430\u0431\u043e\u0440, \u0434\u043e\u0431\u0430\u0432\u043b\u044f\u044e\u0442 \u043e\u0442\u0432\u043b\u0435\u043a\u0430\u044e\u0449\u0438\u0435 \u0432\u0441\u043f\u044b\u0448\u043a\u0438 \u0438\u043b\u0438 \u043e\u0433\u0440\u0430\u043d\u0438\u0447\u0438\u0432\u0430\u044e\u0442 \u0432\u0440\u0435\u043c\u044f \u043d\u0430 \u043e\u0442\u0432\u0435\u0442. \u0412 \u043d\u0435\u043a\u043e\u0442\u043e\u0440\u044b\u0445 \u0432\u0435\u0440\u0441\u0438\u044f\u0445 \u0443\u0437\u043e\u0440 \u0433\u0430\u0441\u043d\u0435\u0442 \u043f\u043e\u0441\u0442\u0435\u043f\u0435\u043d\u043d\u043e \u0438\u043b\u0438 \u0441\u043c\u0435\u0449\u0430\u0435\u0442\u0441\u044f, \u0447\u0442\u043e\u0431\u044b \u0443\u0441\u043b\u043e\u0436\u043d\u0438\u0442\u044c \u043f\u0440\u0438\u043f\u043e\u043c\u0438\u043d\u0430\u043d\u0438\u0435."},en:{about:"Memory Matrix shows a grid in which some cells briefly light up, then go blank. Your job is to reproduce the pattern from memory by tapping exactly the cells that were lit. The grid grows and the patterns get denser as you go, so each round asks you to hold a little more spatial information at once.",benefit:"It trains visuospatial working memory and short-term spatial recall, the ability to hold the where of several items in mind for a few seconds. It also leans on focused attention, since one lapse while the pattern flashes loses the whole round.",history:"The exercise is a digital descendant of classic spatial-span tests from neuropsychology. The grid-and-flash format was popularised for the general public by brain-training apps in the late 2000s and 2010s, with Lumosity's Memory Matrix being the best-known version and the source of the name.",creator:"There is no single inventor. The format comes straight from the Corsi block-tapping test, devised by Canadian-Italian psychologist Philip Corsi around 1972 to 1973 as a spatial counterpart to digit span and to D. O. Hebb's earlier work. The polished grid game most people know was built and named Memory Matrix by Lumos Labs (Lumosity).",methods:"Don't memorise cells one by one. Chunk the lit cells into shapes, lines and clusters, and notice diagonals or symmetry. Keep your eyes near the centre so you see the whole board at once, and silently note rough positions (top-left corner, middle row) rather than counting squares. Push the difficulty until you fail about a third of the time, that edge is where memory span actually stretches.",duration:"Short sessions work best: five to ten minutes, a few times a week, with full attention beats long marathons. Spatial memory tires quickly, so stop once your accuracy clearly drops rather than grinding through fatigue.",research:"Evidence is strongest for exactly what you would expect, you get better at remembering grid patterns and at similar spatial-span tasks. The broader promises are far weaker: meta-analyses of working-memory training, including Melby-Lervag and Hulme's widely cited 2016 review, find little or no reliable far transfer to general intelligence, school performance or everyday memory. Lumosity itself paid a 2 million dollar settlement to the US Federal Trade Commission in 2016 over unsupported brain-training claims, so treat any boost-your-IQ or prevent-decline pitch with real caution.",rec:"Use it as a focused warm-up for spatial attention, not as a cure for forgetfulness, and judge progress by your own span growing over weeks, not by claims about smarter living.",faq:[["Will Memory Matrix make my memory better in real life?","It reliably improves how well you do this and similar grid tasks, but the research does not support broad gains in everyday memory or intelligence. Think of it as targeted exercise for spatial recall, not a general upgrade."],["How is this different from a normal matching memory game?","Matching games (like Concentration) test which symbol is where through trial and error over many flips. Memory Matrix shows the full pattern once, then asks you to reproduce its exact positions from a single brief look, which stresses spatial working memory more directly."],["What's the best way to get a higher score?","Group the lit cells into shapes and lines instead of memorising single squares, keep your gaze near the centre to take in the whole grid, and stay at a difficulty where you fail often enough to be challenged. Comfortable rounds barely train anything."]],variants:"Common variations change grid size (from small 3x3 up to large boards), show several patterns in sequence, ask you to reproduce the order in which cells lit rather than just the set, add distractor flashes, or impose a time limit on your answer. Some versions fade or move the pattern to make recall harder."},es:{about:"Matriz de Memoria te muestra una cuadr\xedcula en la que algunas casillas se iluminan brevemente y luego se apagan. Tu tarea es reproducir el patr\xf3n de memoria tocando exactamente las casillas que estaban encendidas. La cuadr\xedcula crece y los patrones se vuelven m\xe1s densos a medida que avanzas, as\xed que cada ronda te pide retener un poco m\xe1s de informaci\xf3n espacial a la vez.",benefit:"Entrena la memoria de trabajo visoespacial y el recuerdo espacial a corto plazo, la capacidad de mantener en mente el d\xf3nde de varios elementos durante unos segundos. Tambi\xe9n se apoya en la atenci\xf3n concentrada, ya que un solo despiste mientras el patr\xf3n destella echa a perder toda la ronda.",history:"El ejercicio es un descendiente digital de las cl\xe1sicas pruebas de amplitud espacial de la neuropsicolog\xeda. El formato de cuadr\xedcula y destello lo popularizaron entre el p\xfablico general las aplicaciones de entrenamiento cerebral a finales de la d\xe9cada de 2000 y en la de 2010, siendo Memory Matrix de Lumosity la versi\xf3n m\xe1s conocida y el origen del nombre.",creator:"No hay un \xfanico inventor. El formato viene directamente de la prueba de golpeo de bloques de Corsi, ideada por el psic\xf3logo canadiense-italiano Philip Corsi en torno a 1972-1973 como contrapartida espacial de la amplitud de d\xedgitos y a partir del trabajo anterior de D. O. Hebb. El pulido juego de cuadr\xedcula que la mayor\xeda conoce lo construy\xf3 y bautiz\xf3 como Memory Matrix Lumos Labs (Lumosity).",methods:"No memorices las casillas una a una. Agrupa las casillas encendidas en formas, l\xedneas y racimos, y f\xedjate en las diagonales o la simetr\xeda. Mant\xe9n la vista cerca del centro para ver todo el tablero de una vez, y anota mentalmente posiciones aproximadas (esquina superior izquierda, fila central) en lugar de contar cuadros. Sube la dificultad hasta que falles alrededor de un tercio de las veces; ese l\xedmite es donde la amplitud de memoria de verdad se estira.",duration:"Lo que mejor funciona son las sesiones cortas: de cinco a diez minutos, unas pocas veces por semana, con plena atenci\xf3n, vencen a los maratones largos. La memoria espacial se cansa r\xe1pido, as\xed que detente en cuanto tu precisi\xf3n caiga con claridad en vez de forzar la fatiga.",research:"La evidencia es m\xe1s s\xf3lida justo en lo que cabr\xeda esperar: mejoras recordando patrones en cuadr\xedcula y en tareas similares de amplitud espacial. Las promesas m\xe1s amplias son mucho m\xe1s d\xe9biles: los metaan\xe1lisis del entrenamiento de la memoria de trabajo, incluida la muy citada revisi\xf3n de 2016 de Melby-Lerv\xe5g y Hulme, encuentran poca o ninguna transferencia lejana fiable a la inteligencia general, el rendimiento escolar o la memoria cotidiana. La propia Lumosity pag\xf3 en 2016 un acuerdo de 2 millones de d\xf3lares a la Comisi\xf3n Federal de Comercio de EE. UU. por afirmaciones de entrenamiento cerebral sin respaldo, as\xed que toma con verdadera cautela cualquier reclamo de eleva-tu-CI o previene-el-deterioro.",rec:"\xdasalo como calentamiento concentrado para la atenci\xf3n espacial, no como cura para los olvidos, y juzga tu progreso por c\xf3mo crece tu propia amplitud a lo largo de las semanas, no por afirmaciones sobre vivir de forma m\xe1s inteligente.",faq:[["\xbfMatriz de Memoria mejorar\xe1 mi memoria en la vida real?","De forma fiable mejora lo bien que rindes en esta y en tareas de cuadr\xedcula similares, pero la investigaci\xf3n no respalda mejoras amplias en la memoria cotidiana ni en la inteligencia. Piensa en ello como ejercicio espec\xedfico para el recuerdo espacial, no como una mejora general."],["\xbfEn qu\xe9 se diferencia de un juego de memoria de parejas normal?","Los juegos de parejas (como Concentraci\xf3n) ponen a prueba qu\xe9 s\xedmbolo est\xe1 d\xf3nde por ensayo y error a lo largo de muchas vueltas. Matriz de Memoria muestra el patr\xf3n completo una vez y luego te pide reproducir sus posiciones exactas a partir de un \xfanico vistazo breve, lo que exige la memoria de trabajo espacial de forma m\xe1s directa."],["\xbfCu\xe1l es la mejor manera de conseguir m\xe1s puntuaci\xf3n?","Agrupa las casillas encendidas en formas y l\xedneas en lugar de memorizar cuadros sueltos, mant\xe9n la mirada cerca del centro para abarcar toda la cuadr\xedcula, y qu\xe9date en una dificultad en la que falles lo suficiente como para que te suponga un reto. Las rondas c\xf3modas apenas entrenan nada."]],variants:"Las variantes habituales cambian el tama\xf1o de la cuadr\xedcula (desde peque\xf1as de 3x3 hasta tableros grandes), muestran varios patrones en secuencia, te piden reproducir el orden en que se iluminaron las casillas en lugar de solo el conjunto, a\xf1aden destellos distractores o imponen un l\xedmite de tiempo a tu respuesta. Algunas versiones desvanecen o mueven el patr\xf3n para dificultar el recuerdo."},de:{about:"Memory Matrix zeigt ein Raster, in dem einige Zellen kurz aufleuchten und dann wieder erl\xf6schen. Deine Aufgabe ist es, das Muster aus dem Ged\xe4chtnis wiederzugeben, indem du genau die Zellen antippst, die aufgeleuchtet haben. Das Raster w\xe4chst und die Muster werden dichter, je weiter du kommst, sodass jede Runde verlangt, ein wenig mehr r\xe4umliche Information auf einmal zu behalten.",benefit:"Es trainiert das visuell-r\xe4umliche Arbeitsged\xe4chtnis und den kurzfristigen r\xe4umlichen Abruf \u2013 die F\xe4higkeit, das Wo mehrerer Elemente f\xfcr ein paar Sekunden im Kopf zu halten. Es beansprucht auch die gezielte Aufmerksamkeit, denn ein einziger Aussetzer, w\xe4hrend das Muster aufblitzt, kostet die ganze Runde.",history:"Die \xdcbung ist ein digitaler Nachfahre klassischer r\xe4umlicher Spannen-Tests aus der Neuropsychologie. Das Raster-und-Aufblitz-Format wurde Ende der 2000er- und in den 2010er-Jahren von Gehirntraining-Apps in der breiten \xd6ffentlichkeit bekannt gemacht, wobei Lumositys Memory Matrix die bekannteste Variante und die Quelle des Namens ist.",creator:"Es gibt keinen einzelnen Erfinder. Das Format stammt unmittelbar vom Corsi-Block-Tapping-Test, den der kanadisch-italienische Psychologe Philip Corsi um 1972 bis 1973 als r\xe4umliches Gegenst\xfcck zur Zahlenspanne und in Anlehnung an die fr\xfchere Arbeit von D. O. Hebb entwarf. Das ausgefeilte Rasterspiel, das die meisten kennen, wurde von Lumos Labs (Lumosity) gebaut und Memory Matrix benannt.",methods:"Pr\xe4ge dir die Zellen nicht einzeln ein. B\xfcndle die leuchtenden Zellen zu Formen, Linien und Gruppen und achte auf Diagonalen oder Symmetrie. Halte den Blick nahe der Mitte, damit du das ganze Brett auf einmal siehst, und merke dir leise grobe Positionen (obere linke Ecke, mittlere Reihe), statt Felder zu z\xe4hlen. Treibe die Schwierigkeit so weit, dass du etwa ein Drittel der Zeit scheiterst \u2013 an dieser Grenze dehnt sich die Ged\xe4chtnisspanne tats\xe4chlich.",duration:"Kurze Sitzungen funktionieren am besten: f\xfcnf bis zehn Minuten, ein paar Mal pro Woche, mit voller Aufmerksamkeit schlagen lange Marathons. Das r\xe4umliche Ged\xe4chtnis erm\xfcdet schnell, also h\xf6r auf, sobald deine Treffsicherheit deutlich nachl\xe4sst, statt dich durch die Ersch\xf6pfung zu qu\xe4len.",research:"Am besten belegt ist genau das, was man erwarten w\xfcrde: Du wirst besser darin, dir Rastermuster zu merken, und in \xe4hnlichen r\xe4umlichen Spannen-Aufgaben. Die breiteren Versprechen sind weit schw\xe4cher: Meta-Analysen zum Arbeitsged\xe4chtnistraining, darunter die viel zitierte \xdcbersicht von Melby-Lerv\xe5g und Hulme aus dem Jahr 2016, finden kaum oder keinen verl\xe4sslichen Ferntransfer auf die allgemeine Intelligenz, die Schulleistung oder das Alltagsged\xe4chtnis. Lumosity selbst zahlte 2016 einen Vergleich von 2 Millionen Dollar an die US-Handelskommission (FTC) wegen unbelegter Gehirntraining-Behauptungen \u2013 jedes Versprechen, den IQ zu steigern oder den Abbau zu verhindern, also mit echter Vorsicht behandeln.",rec:"Nutze es als gezieltes Aufw\xe4rmen f\xfcr die r\xe4umliche Aufmerksamkeit, nicht als Mittel gegen Vergesslichkeit, und beurteile den Fortschritt daran, dass deine eigene Spanne \xfcber Wochen w\xe4chst, nicht an Versprechen \xfcber ein kl\xfcgeres Leben.",faq:[["Macht Memory Matrix mein Ged\xe4chtnis im echten Leben besser?","Es verbessert verl\xe4sslich, wie gut du diese und \xe4hnliche Rasteraufgaben l\xf6st, aber die Forschung st\xfctzt keine breiten Verbesserungen des Alltagsged\xe4chtnisses oder der Intelligenz. Betrachte es als gezielte \xdcbung f\xfcr den r\xe4umlichen Abruf, nicht als allgemeines Upgrade."],["Worin unterscheidet sich das von einem normalen Memory-Spiel?","Memory-Spiele (wie Concentration) pr\xfcfen durch Versuch und Irrtum \xfcber viele Umdrehungen, welches Symbol wo liegt. Memory Matrix zeigt das vollst\xe4ndige Muster einmal und verlangt dann, seine genauen Positionen aus einem einzigen kurzen Blick wiederzugeben, was das r\xe4umliche Arbeitsged\xe4chtnis unmittelbarer fordert."],["Wie erreicht man am besten eine h\xf6here Punktzahl?","B\xfcndle die leuchtenden Zellen zu Formen und Linien, statt einzelne Felder zu lernen, halte den Blick nahe der Mitte, um das ganze Raster aufzunehmen, und bleib bei einer Schwierigkeit, bei der du oft genug scheiterst, um gefordert zu sein. Bequeme Runden trainieren kaum etwas."]],variants:"\xdcbliche Variationen \xe4ndern die Rastergr\xf6\xdfe (von kleinen 3\xd73 bis zu gro\xdfen Brettern), zeigen mehrere Muster nacheinander, verlangen, die Reihenfolge des Aufleuchtens wiederzugeben statt nur die Menge, f\xfcgen ablenkende Aufblitze hinzu oder setzen der Antwort ein Zeitlimit. Manche Versionen blenden das Muster aus oder bewegen es, um den Abruf zu erschweren."},pt:{about:"Memory Matrix mostra uma grade na qual algumas c\xe9lulas se acendem por um instante e depois apagam. Seu trabalho \xe9 reproduzir o padr\xe3o de mem\xf3ria, tocando exatamente as c\xe9lulas que estavam acesas. A grade cresce e os padr\xf5es ficam mais densos \xe0 medida que voc\xea avan\xe7a, ent\xe3o cada rodada pede que voc\xea segure um pouco mais de informa\xe7\xe3o espacial de uma vez.",benefit:"Treina a mem\xf3ria de trabalho visuoespacial e a recorda\xe7\xe3o espacial de curto prazo, a capacidade de manter na cabe\xe7a o \"onde\" de v\xe1rios itens por alguns segundos. Tamb\xe9m depende da aten\xe7\xe3o focada, j\xe1 que um \xfanico cochilo enquanto o padr\xe3o pisca faz voc\xea perder a rodada inteira.",history:"O exerc\xedcio \xe9 um descendente digital dos cl\xe1ssicos testes de amplitude espacial da neuropsicologia. O formato de grade que pisca foi popularizado para o p\xfablico geral pelos aplicativos de treino cerebral no fim dos anos 2000 e na d\xe9cada de 2010, sendo o Memory Matrix da Lumosity a vers\xe3o mais conhecida e a origem do nome.",creator:"N\xe3o h\xe1 um \xfanico inventor. O formato vem diretamente do teste de toque de blocos de Corsi, criado pelo psic\xf3logo \xedtalo-canadense Philip Corsi por volta de 1972 a 1973 como contraparte espacial do digit span e a partir do trabalho anterior de D. O. Hebb. O jogo de grade refinado que a maioria das pessoas conhece foi constru\xeddo e batizado de Memory Matrix pela Lumos Labs (Lumosity).",methods:"N\xe3o decore as c\xe9lulas uma a uma. Agrupe as c\xe9lulas acesas em formas, linhas e aglomerados, e repare em diagonais ou simetrias. Mantenha os olhos perto do centro para enxergar todo o tabuleiro de uma vez, e anote mentalmente as posi\xe7\xf5es aproximadas (canto superior esquerdo, linha do meio) em vez de contar quadrados. Aumente a dificuldade at\xe9 falhar cerca de um ter\xe7o das vezes: esse limite \xe9 onde a amplitude da mem\xf3ria de fato se estica.",duration:"Sess\xf5es curtas funcionam melhor: cinco a dez minutos, algumas vezes por semana, com aten\xe7\xe3o total, vencem as maratonas longas. A mem\xf3ria espacial cansa r\xe1pido, ent\xe3o pare assim que sua precis\xe3o cair de forma clara, em vez de insistir na fadiga.",research:"A evid\xeancia \xe9 mais forte exatamente para o que se esperaria: voc\xea fica melhor em lembrar padr\xf5es em grade e em tarefas semelhantes de amplitude espacial. As promessas mais amplas s\xe3o bem mais fracas: meta-an\xe1lises de treino de mem\xf3ria de trabalho, incluindo a bastante citada revis\xe3o de 2016 de Melby-Lerv\xe5g e Hulme, encontram pouca ou nenhuma transfer\xeancia ampla confi\xe1vel para a intelig\xeancia geral, o desempenho escolar ou a mem\xf3ria do dia a dia. A pr\xf3pria Lumosity pagou um acordo de 2 milh\xf5es de d\xf3lares \xe0 Comiss\xe3o Federal de Com\xe9rcio dos EUA em 2016 por alega\xe7\xf5es sem respaldo sobre treino cerebral, ent\xe3o encare qualquer promessa de turbinar o QI ou prevenir o decl\xednio com real cautela.",rec:"Use-o como um aquecimento focado para a aten\xe7\xe3o espacial, n\xe3o como cura para o esquecimento, e avalie o progresso pelo seu pr\xf3prio limite crescendo ao longo de semanas, n\xe3o por alega\xe7\xf5es de uma vida mais inteligente.",faq:[["O Memory Matrix vai melhorar minha mem\xf3ria na vida real?","Ele melhora de forma confi\xe1vel o seu desempenho nesta e em tarefas de grade semelhantes, mas a pesquisa n\xe3o respalda ganhos amplos na mem\xf3ria ou na intelig\xeancia do dia a dia. Pense nele como um exerc\xedcio direcionado para a recorda\xe7\xe3o espacial, n\xe3o como uma melhoria geral."],["Em que isso difere de um jogo comum de mem\xf3ria de pares?","Os jogos de pares (como o Concentra\xe7\xe3o) testam qual s\xedmbolo est\xe1 onde por tentativa e erro ao longo de muitas viradas. O Memory Matrix mostra o padr\xe3o completo uma vez e depois pede que voc\xea reproduza as posi\xe7\xf5es exatas a partir de um \xfanico olhar breve, o que exige mais diretamente a mem\xf3ria de trabalho espacial."],["Qual \xe9 a melhor forma de conseguir uma pontua\xe7\xe3o mais alta?","Agrupe as c\xe9lulas acesas em formas e linhas em vez de decorar quadrados isolados, mantenha o olhar perto do centro para abarcar a grade inteira, e fique numa dificuldade em que voc\xea falhe com frequ\xeancia suficiente para ser desafiado. Rodadas confort\xe1veis quase n\xe3o treinam nada."]],variants:"As varia\xe7\xf5es comuns mudam o tamanho da grade (de uma pequena 3x3 at\xe9 tabuleiros grandes), mostram v\xe1rios padr\xf5es em sequ\xeancia, pedem que voc\xea reproduza a ordem em que as c\xe9lulas acenderam, e n\xe3o apenas o conjunto, acrescentam piscadas distratoras ou imp\xf5em um limite de tempo para a resposta. Algumas vers\xf5es fazem o padr\xe3o sumir aos poucos ou se mover, para dificultar a recorda\xe7\xe3o."},hi:{about:"\u092e\u0947\u092e\u094b\u0930\u0940 \u092e\u0948\u091f\u094d\u0930\u093f\u0915\u094d\u0938 \u090f\u0915 \u0917\u094d\u0930\u093f\u0921 \u0926\u093f\u0916\u093e\u0924\u093e \u0939\u0948 \u091c\u093f\u0938\u092e\u0947\u0902 \u0915\u0941\u091b \u0915\u094b\u0936\u093f\u0915\u093e\u090f\u0901 \u092a\u0932 \u092d\u0930 \u0915\u0947 \u0932\u093f\u090f \u091c\u0932 \u0909\u0920\u0924\u0940 \u0939\u0948\u0902, \u092b\u093f\u0930 \u092c\u0941\u091d \u091c\u093e\u0924\u0940 \u0939\u0948\u0902\u0964 \u0906\u092a\u0915\u093e \u0915\u093e\u092e \u0939\u0948 \u0920\u0940\u0915 \u0935\u0939\u0940 \u0915\u094b\u0936\u093f\u0915\u093e\u090f\u0901 \u091b\u0942\u0915\u0930 \u0907\u0938 \u092a\u0948\u091f\u0930\u094d\u0928 \u0915\u094b \u0938\u094d\u092e\u0943\u0924\u093f \u0938\u0947 \u0926\u094b\u092c\u093e\u0930\u093e \u092c\u0928\u093e\u0928\u093e \u091c\u094b \u091c\u0932\u0940 \u0925\u0940\u0902\u0964 \u091c\u0948\u0938\u0947-\u091c\u0948\u0938\u0947 \u0906\u092a \u0906\u0917\u0947 \u092c\u0922\u093c\u0924\u0947 \u0939\u0948\u0902, \u0917\u094d\u0930\u093f\u0921 \u092c\u0921\u093c\u0940 \u0939\u094b\u0924\u0940 \u091c\u093e\u0924\u0940 \u0939\u0948 \u0914\u0930 \u092a\u0948\u091f\u0930\u094d\u0928 \u0938\u0918\u0928 \u2014 \u0907\u0938\u0932\u093f\u090f \u0939\u0930 \u0926\u094c\u0930 \u0906\u092a\u0938\u0947 \u090f\u0915 \u0938\u093e\u0925 \u0925\u094b\u0921\u093c\u0940 \u0914\u0930 \u0938\u094d\u0925\u093e\u0928\u093f\u0915 \u091c\u093e\u0928\u0915\u093e\u0930\u0940 \u0930\u0916\u0928\u0947 \u0915\u094b \u0915\u0939\u0924\u093e \u0939\u0948\u0964",benefit:"\u092f\u0939 \u0926\u0943\u0936\u094d\u092f-\u0938\u094d\u0925\u093e\u0928\u093f\u0915 \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932 \u0938\u094d\u092e\u0943\u0924\u093f \u0914\u0930 \u0905\u0932\u094d\u092a\u0915\u093e\u0932\u093f\u0915 \u0938\u094d\u0925\u093e\u0928\u093f\u0915 \u0938\u094d\u092e\u0930\u0923 \u0915\u094b \u0938\u093e\u0927\u0924\u093e \u0939\u0948 \u2014 \u0915\u0941\u091b \u0938\u0947\u0915\u0902\u0921 \u0915\u0947 \u0932\u093f\u090f \u0915\u0908 \u091a\u0940\u091c\u093c\u094b\u0902 \u0915\u0947 \"\u0915\u0939\u093e\u0901\" \u0915\u094b \u092e\u0928 \u092e\u0947\u0902 \u0930\u0916\u0928\u0947 \u0915\u0940 \u0915\u094d\u0937\u092e\u0924\u093e\u0964 \u092f\u0939 \u0915\u0947\u0902\u0926\u094d\u0930\u093f\u0924 \u0927\u094d\u092f\u093e\u0928 \u092a\u0930 \u092d\u0940 \u091f\u093f\u0915\u093e \u0939\u0948, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u092a\u0948\u091f\u0930\u094d\u0928 \u091d\u0932\u0915\u0924\u0947 \u0938\u092e\u092f \u090f\u0915 \u091a\u0942\u0915 \u092a\u0942\u0930\u093e \u0926\u094c\u0930 \u0917\u0901\u0935\u093e \u0926\u0947\u0924\u0940 \u0939\u0948\u0964",history:"\u092f\u0939 \u0905\u092d\u094d\u092f\u093e\u0938 \u0924\u0902\u0924\u094d\u0930\u093f\u0915\u093e-\u092e\u0928\u094b\u0935\u093f\u091c\u094d\u091e\u093e\u0928 \u0915\u0947 \u0915\u094d\u0932\u093e\u0938\u093f\u0915 \u0938\u094d\u0925\u093e\u0928\u093f\u0915-\u0938\u094d\u092a\u0948\u0928 \u092a\u0930\u0940\u0915\u094d\u0937\u0923\u094b\u0902 \u0915\u093e \u090f\u0915 \u0921\u093f\u091c\u093f\u091f\u0932 \u0935\u0902\u0936\u091c \u0939\u0948\u0964 \u0917\u094d\u0930\u093f\u0921-\u0914\u0930-\u091d\u0932\u0915 \u0935\u093e\u0932\u093e \u092f\u0939 \u092a\u094d\u0930\u093e\u0930\u0942\u092a 2000 \u0915\u0947 \u0926\u0936\u0915 \u0915\u0947 \u0906\u0916\u093c\u093f\u0930 \u0914\u0930 2010 \u0915\u0947 \u0926\u0936\u0915 \u092e\u0947\u0902 \u092c\u094d\u0930\u0947\u0928-\u091f\u094d\u0930\u0947\u0928\u093f\u0902\u0917 \u0910\u092a\u094d\u0938 \u0928\u0947 \u0906\u092e \u091c\u0928\u0924\u093e \u0915\u0947 \u092c\u0940\u091a \u0932\u094b\u0915\u092a\u094d\u0930\u093f\u092f \u0915\u093f\u092f\u093e, \u091c\u093f\u0938\u092e\u0947\u0902 Lumosity \u0915\u093e \u092e\u0947\u092e\u094b\u0930\u0940 \u092e\u0948\u091f\u094d\u0930\u093f\u0915\u094d\u0938 \u0938\u092c\u0938\u0947 \u091c\u093e\u0928\u093e-\u092e\u093e\u0928\u093e \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0914\u0930 \u0907\u0938 \u0928\u093e\u092e \u0915\u093e \u0938\u094d\u0930\u094b\u0924 \u0939\u0948\u0964",creator:"\u0907\u0938\u0915\u093e \u0915\u094b\u0908 \u090f\u0915 \u0906\u0935\u093f\u0937\u094d\u0915\u093e\u0930\u0915 \u0928\u0939\u0940\u0902 \u0939\u0948\u0964 \u092f\u0939 \u092a\u094d\u0930\u093e\u0930\u0942\u092a \u0938\u0940\u0927\u0947 \u0915\u0949\u0930\u094d\u0938\u0940 \u092c\u094d\u0932\u0949\u0915-\u091f\u0948\u092a\u093f\u0902\u0917 \u092a\u0930\u0940\u0915\u094d\u0937\u0923 \u0938\u0947 \u0906\u0924\u093e \u0939\u0948, \u091c\u093f\u0938\u0947 \u0915\u0928\u093e\u0921\u093e\u0908-\u0907\u0924\u093e\u0932\u0935\u0940 \u092e\u0928\u094b\u0935\u0948\u091c\u094d\u091e\u093e\u0928\u093f\u0915 \u092b\u093c\u093f\u0932\u093f\u092a \u0915\u0949\u0930\u094d\u0938\u0940 (Philip Corsi) \u0928\u0947 \u0932\u0917\u092d\u0917 1972 \u0938\u0947 1973 \u092e\u0947\u0902 \u0921\u093f\u091c\u093f\u091f \u0938\u094d\u092a\u0948\u0928 \u0915\u0947 \u0938\u094d\u0925\u093e\u0928\u093f\u0915 \u0938\u092e\u0915\u0915\u094d\u0937 \u0914\u0930 \u0921\u0940. \u0913. \u0939\u0947\u092c\u094d\u092c \u0915\u0947 \u092a\u0939\u0932\u0947 \u0915\u0947 \u0915\u093e\u092e \u0915\u0947 \u0906\u0927\u093e\u0930 \u092a\u0930 \u0930\u091a\u093e\u0964 \u091c\u093c\u094d\u092f\u093e\u0926\u093e\u0924\u0930 \u0932\u094b\u0917 \u091c\u093f\u0938 \u0928\u093f\u0916\u0930\u0947 \u0917\u094d\u0930\u093f\u0921-\u0917\u0947\u092e \u0915\u094b \u091c\u093e\u0928\u0924\u0947 \u0939\u0948\u0902, \u0909\u0938\u0947 Lumos Labs (Lumosity) \u0928\u0947 \u092c\u0928\u093e\u092f\u093e \u0914\u0930 \u092e\u0947\u092e\u094b\u0930\u0940 \u092e\u0948\u091f\u094d\u0930\u093f\u0915\u094d\u0938 \u0928\u093e\u092e \u0926\u093f\u092f\u093e\u0964",methods:"\u0915\u094b\u0936\u093f\u0915\u093e\u0913\u0902 \u0915\u094b \u090f\u0915-\u090f\u0915 \u0915\u0930\u0915\u0947 \u0930\u091f\u0947\u0902 \u0928\u0939\u0940\u0902\u0964 \u091c\u0932\u0940 \u0939\u0941\u0908 \u0915\u094b\u0936\u093f\u0915\u093e\u0913\u0902 \u0915\u094b \u0906\u0915\u0943\u0924\u093f\u092f\u094b\u0902, \u0930\u0947\u0916\u093e\u0913\u0902 \u0914\u0930 \u0917\u0941\u091a\u094d\u091b\u094b\u0902 \u092e\u0947\u0902 \u092c\u093e\u0901\u091f\u0915\u0930 \u0926\u0947\u0916\u0947\u0902, \u0914\u0930 \u0935\u093f\u0915\u0930\u094d\u0923\u094b\u0902 \u092f\u093e \u0938\u092e\u0930\u0942\u092a\u0924\u093e \u092a\u0930 \u0927\u094d\u092f\u093e\u0928 \u0926\u0947\u0902\u0964 \u0905\u092a\u0928\u0940 \u0928\u091c\u093c\u0930 \u092c\u0940\u091a \u0915\u0947 \u092a\u093e\u0938 \u0930\u0916\u0947\u0902 \u0924\u093e\u0915\u093f \u092a\u0942\u0930\u093e \u092c\u094b\u0930\u094d\u0921 \u090f\u0915 \u0938\u093e\u0925 \u0926\u093f\u0916\u0947, \u0914\u0930 \u091a\u094c\u0915\u094b\u0930\u094b\u0902 \u0915\u094b \u0917\u093f\u0928\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u092e\u0928-\u0939\u0940-\u092e\u0928 \u092e\u094b\u091f\u0947-\u092e\u094b\u091f\u0947 \u0938\u094d\u0925\u093e\u0928 \u0928\u094b\u091f \u0915\u0930\u0947\u0902 (\u090a\u092a\u0930\u0940-\u092c\u093e\u090f\u0901 \u0915\u094b\u0928\u093e, \u092c\u0940\u091a \u0915\u0940 \u092a\u0902\u0915\u094d\u0924\u093f)\u0964 \u0915\u0920\u093f\u0928\u093e\u0908 \u0915\u094b \u0935\u0939\u093e\u0901 \u0924\u0915 \u0927\u0915\u0947\u0932\u0947\u0902 \u091c\u0939\u093e\u0901 \u0906\u092a \u0932\u0917\u092d\u0917 \u090f\u0915-\u0924\u093f\u0939\u093e\u0908 \u092c\u093e\u0930 \u091a\u0942\u0915\u0947\u0902 \u2014 \u0935\u0939\u0940 \u0915\u093f\u0928\u093e\u0930\u093e \u0939\u0948 \u091c\u0939\u093e\u0901 \u0938\u094d\u092e\u0943\u0924\u093f-\u0938\u094d\u092a\u0948\u0928 \u0938\u091a\u092e\u0941\u091a \u092b\u0948\u0932\u0924\u093e \u0939\u0948\u0964",duration:"\u091b\u094b\u091f\u0947 \u0938\u0924\u094d\u0930 \u0938\u092c\u0938\u0947 \u0905\u091a\u094d\u091b\u0947 \u0930\u0939\u0924\u0947 \u0939\u0948\u0902: \u092a\u093e\u0901\u091a \u0938\u0947 \u0926\u0938 \u092e\u093f\u0928\u091f, \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u0915\u0941\u091b \u092c\u093e\u0930, \u092a\u0942\u0930\u0947 \u0927\u094d\u092f\u093e\u0928 \u0915\u0947 \u0938\u093e\u0925 \u2014 \u092f\u0939 \u0932\u0902\u092c\u0947 \u092e\u0948\u0930\u093e\u0925\u0928 \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u0939\u0948\u0964 \u0938\u094d\u0925\u093e\u0928\u093f\u0915 \u0938\u094d\u092e\u0943\u0924\u093f \u091c\u0932\u094d\u0926\u0940 \u0925\u0915 \u091c\u093e\u0924\u0940 \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0925\u0915\u093e\u0928 \u092e\u0947\u0902 \u0930\u0917\u0921\u093c\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u091c\u0948\u0938\u0947 \u0939\u0940 \u0906\u092a\u0915\u0940 \u0938\u091f\u0940\u0915\u0924\u093e \u0938\u093e\u092b\u093c \u0917\u093f\u0930\u0928\u0947 \u0932\u0917\u0947, \u0930\u0941\u0915 \u091c\u093e\u090f\u0901\u0964",research:"\u091c\u093f\u0938\u0915\u0940 \u0905\u092a\u0947\u0915\u094d\u0937\u093e \u0939\u0948, \u092a\u094d\u0930\u092e\u093e\u0923 \u0920\u0940\u0915 \u0909\u0938\u0940 \u0915\u0947 \u0932\u093f\u090f \u0938\u092c\u0938\u0947 \u092e\u091c\u093c\u092c\u0942\u0924 \u0939\u0948\u0902 \u2014 \u0917\u094d\u0930\u093f\u0921 \u092a\u0948\u091f\u0930\u094d\u0928 \u092f\u093e\u0926 \u0930\u0916\u0928\u0947 \u0914\u0930 \u092e\u093f\u0932\u0924\u0947-\u091c\u0941\u0932\u0924\u0947 \u0938\u094d\u0925\u093e\u0928\u093f\u0915-\u0938\u094d\u092a\u0948\u0928 \u0915\u093e\u0930\u094d\u092f\u094b\u0902 \u092e\u0947\u0902 \u0906\u092a \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902\u0964 \u092c\u0921\u093c\u0947 \u0935\u093e\u0926\u0947 \u0915\u0939\u0940\u0902 \u0915\u092e\u091c\u093c\u094b\u0930 \u0939\u0948\u0902: \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932-\u0938\u094d\u092e\u0943\u0924\u093f \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u0915\u0947 \u092e\u0947\u091f\u093e-\u0935\u093f\u0936\u094d\u0932\u0947\u0937\u0923, \u091c\u093f\u0928\u092e\u0947\u0902 Melby-Lerv\xe5g \u0914\u0930 Hulme \u0915\u0940 \u0935\u094d\u092f\u093e\u092a\u0915 \u0930\u0942\u092a \u0938\u0947 \u0909\u0926\u094d\u0927\u0943\u0924 2016 \u0915\u0940 \u0938\u092e\u0940\u0915\u094d\u0937\u093e \u0936\u093e\u092e\u093f\u0932 \u0939\u0948, \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u092c\u0941\u0926\u094d\u0927\u093f, \u092a\u0922\u093c\u093e\u0908 \u0915\u0947 \u092a\u094d\u0930\u0926\u0930\u094d\u0936\u0928 \u092f\u093e \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0940 \u0938\u094d\u092e\u0943\u0924\u093f \u0924\u0915 \u0915\u094b\u0908 \u092f\u093e \u092c\u0939\u0941\u0924 \u0915\u092e \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0926\u0942\u0930-\u0939\u0938\u094d\u0924\u093e\u0902\u0924\u0930\u0923 \u092a\u093e\u0924\u0947 \u0939\u0948\u0902\u0964 Lumosity \u0928\u0947 \u0916\u093c\u0941\u0926 2016 \u092e\u0947\u0902 \u092c\u093f\u0928\u093e \u0938\u092c\u0942\u0924 \u0935\u093e\u0932\u0947 \u092c\u094d\u0930\u0947\u0928-\u091f\u094d\u0930\u0947\u0928\u093f\u0902\u0917 \u0926\u093e\u0935\u094b\u0902 \u0915\u094b \u0932\u0947\u0915\u0930 \u0905\u092e\u0947\u0930\u093f\u0915\u0940 \u092b\u093c\u0947\u0921\u0930\u0932 \u091f\u094d\u0930\u0947\u0921 \u0915\u092e\u0940\u0936\u0928 \u0915\u094b 2 \u0915\u0930\u094b\u0921\u093c \u0921\u0949\u0932\u0930 \u0915\u093e \u0938\u092e\u091d\u094c\u0924\u093e-\u091c\u0941\u0930\u094d\u092e\u093e\u0928\u093e \u091a\u0941\u0915\u093e\u092f\u093e, \u0907\u0938\u0932\u093f\u090f \u0915\u093f\u0938\u0940 \u092d\u0940 \"IQ \u092c\u0922\u093c\u093e\u0913\" \u092f\u093e \"\u0917\u093f\u0930\u093e\u0935\u091f \u0930\u094b\u0915\u094b\" \u0935\u093e\u0932\u0940 \u092c\u093e\u0924 \u0915\u094b \u0938\u091a\u092e\u0941\u091a \u0938\u093e\u0935\u0927\u093e\u0928\u0940 \u0938\u0947 \u0932\u0947\u0902\u0964",rec:"\u0907\u0938\u0947 \u092d\u0942\u0932\u0928\u0947 \u0915\u0940 \u092c\u0940\u092e\u093e\u0930\u0940 \u0915\u093e \u0907\u0932\u093e\u091c \u092e\u093e\u0928\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u0938\u094d\u0925\u093e\u0928\u093f\u0915 \u0927\u094d\u092f\u093e\u0928 \u0915\u0947 \u090f\u0915 \u0915\u0947\u0902\u0926\u094d\u0930\u093f\u0924 \u0935\u093e\u0930\u094d\u092e-\u0905\u092a \u0915\u0940 \u0924\u0930\u0939 \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0915\u0930\u0947\u0902, \u0914\u0930 \u092a\u094d\u0930\u0917\u0924\u093f \u0915\u094b \"\u0939\u094b\u0936\u093f\u092f\u093e\u0930 \u091c\u0940\u0935\u0928\" \u0915\u0947 \u0926\u093e\u0935\u094b\u0902 \u0938\u0947 \u0928\u0939\u0940\u0902, \u092c\u0932\u094d\u0915\u093f \u0939\u092b\u093c\u094d\u0924\u094b\u0902 \u092e\u0947\u0902 \u0905\u092a\u0928\u0947 \u0939\u0940 \u0938\u094d\u092a\u0948\u0928 \u0915\u0947 \u092c\u0922\u093c\u0928\u0947 \u0938\u0947 \u0906\u0901\u0915\u0947\u0902\u0964",faq:[["\u0915\u094d\u092f\u093e \u092e\u0947\u092e\u094b\u0930\u0940 \u092e\u0948\u091f\u094d\u0930\u093f\u0915\u094d\u0938 \u0905\u0938\u0932 \u091c\u093c\u093f\u0902\u0926\u0917\u0940 \u092e\u0947\u0902 \u092e\u0947\u0930\u0940 \u0938\u094d\u092e\u0943\u0924\u093f \u092c\u0947\u0939\u0924\u0930 \u0915\u0930\u0947\u0917\u093e?","\u092f\u0939 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0930\u0942\u092a \u0938\u0947 \u0938\u0941\u0927\u093e\u0930\u0924\u093e \u0939\u0948 \u0915\u093f \u0906\u092a \u0907\u0938 \u0914\u0930 \u092e\u093f\u0932\u0924\u0947-\u091c\u0941\u0932\u0924\u0947 \u0917\u094d\u0930\u093f\u0921 \u0915\u093e\u0930\u094d\u092f\u094b\u0902 \u092e\u0947\u0902 \u0915\u093f\u0924\u0928\u093e \u0905\u091a\u094d\u091b\u093e \u0915\u0930\u0924\u0947 \u0939\u0948\u0902, \u092a\u0930 \u0936\u094b\u0927 \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0940 \u0938\u094d\u092e\u0943\u0924\u093f \u092f\u093e \u092c\u0941\u0926\u094d\u0927\u093f \u092e\u0947\u0902 \u0935\u094d\u092f\u093e\u092a\u0915 \u0932\u093e\u092d \u0915\u093e \u0938\u092e\u0930\u094d\u0925\u0928 \u0928\u0939\u0940\u0902 \u0915\u0930\u0924\u093e\u0964 \u0907\u0938\u0947 \u0938\u094d\u0925\u093e\u0928\u093f\u0915 \u0938\u094d\u092e\u0930\u0923 \u0915\u0947 \u0932\u093f\u090f \u0932\u0915\u094d\u0937\u093f\u0924 \u0935\u094d\u092f\u093e\u092f\u093e\u092e \u0938\u092e\u091d\u0947\u0902, \u0915\u094b\u0908 \u0938\u0930\u094d\u0935\u0935\u094d\u092f\u093e\u092a\u0940 \u0938\u0941\u0927\u093e\u0930 \u0928\u0939\u0940\u0902\u0964"],["\u092f\u0939 \u090f\u0915 \u0906\u092e \u092e\u0948\u091a\u093f\u0902\u0917 \u092e\u0947\u092e\u094b\u0930\u0940 \u0916\u0947\u0932 \u0938\u0947 \u0915\u0948\u0938\u0947 \u0905\u0932\u0917 \u0939\u0948?","\u092e\u0948\u091a\u093f\u0902\u0917 \u0916\u0947\u0932 (\u091c\u0948\u0938\u0947 \u0915\u0902\u0938\u0928\u094d\u091f\u094d\u0930\u0947\u0936\u0928) \u0915\u0908 \u092c\u093e\u0930 \u092a\u0932\u091f\u0915\u0930, \u0906\u091c\u093c\u092e\u093e\u0907\u0936 \u0938\u0947 \u091c\u093e\u0901\u091a\u0924\u0947 \u0939\u0948\u0902 \u0915\u093f \u0915\u094c\u0928-\u0938\u093e \u091a\u093f\u0939\u094d\u0928 \u0915\u0939\u093e\u0901 \u0939\u0948\u0964 \u092e\u0947\u092e\u094b\u0930\u0940 \u092e\u0948\u091f\u094d\u0930\u093f\u0915\u094d\u0938 \u092a\u0942\u0930\u093e \u092a\u0948\u091f\u0930\u094d\u0928 \u090f\u0915 \u092c\u093e\u0930 \u0926\u093f\u0916\u093e\u0924\u093e \u0939\u0948, \u092b\u093f\u0930 \u090f\u0915 \u0939\u0940 \u091d\u0932\u0915 \u0938\u0947 \u0909\u0938\u0915\u0947 \u0938\u091f\u0940\u0915 \u0938\u094d\u0925\u093e\u0928\u094b\u0902 \u0915\u094b \u0926\u094b\u092c\u093e\u0930\u093e \u092c\u0928\u093e\u0928\u0947 \u0915\u094b \u0915\u0939\u0924\u093e \u0939\u0948, \u091c\u094b \u0938\u094d\u0925\u093e\u0928\u093f\u0915 \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932 \u0938\u094d\u092e\u0943\u0924\u093f \u092a\u0930 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0938\u0940\u0927\u093e \u091c\u093c\u094b\u0930 \u0921\u093e\u0932\u0924\u093e \u0939\u0948\u0964"],["\u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0938\u094d\u0915\u094b\u0930 \u092a\u093e\u0928\u0947 \u0915\u093e \u0938\u092c\u0938\u0947 \u0905\u091a\u094d\u091b\u093e \u0924\u0930\u0940\u0915\u093e \u0915\u094d\u092f\u093e \u0939\u0948?","\u0905\u0915\u0947\u0932\u0947 \u091a\u094c\u0915\u094b\u0930\u094b\u0902 \u0915\u094b \u0930\u091f\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u091c\u0932\u0940 \u0915\u094b\u0936\u093f\u0915\u093e\u0913\u0902 \u0915\u094b \u0906\u0915\u0943\u0924\u093f\u092f\u094b\u0902 \u0914\u0930 \u0930\u0947\u0916\u093e\u0913\u0902 \u092e\u0947\u0902 \u092c\u093e\u0901\u091f\u0947\u0902, \u092a\u0942\u0930\u0940 \u0917\u094d\u0930\u093f\u0921 \u0915\u094b \u0938\u092e\u0947\u091f\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0905\u092a\u0928\u0940 \u0928\u091c\u093c\u0930 \u092c\u0940\u091a \u0915\u0947 \u092a\u093e\u0938 \u0930\u0916\u0947\u0902, \u0914\u0930 \u0910\u0938\u0940 \u0915\u0920\u093f\u0928\u093e\u0908 \u092a\u0930 \u092c\u0928\u0947 \u0930\u0939\u0947\u0902 \u091c\u0939\u093e\u0901 \u0906\u092a \u0907\u0924\u0928\u093e \u091a\u0942\u0915\u0947\u0902 \u0915\u093f \u091a\u0941\u0928\u094c\u0924\u0940 \u092c\u0928\u0940 \u0930\u0939\u0947\u0964 \u0906\u0938\u093e\u0928 \u0926\u094c\u0930 \u0932\u0917\u092d\u0917 \u0915\u0941\u091b \u0928\u0939\u0940\u0902 \u0938\u093f\u0916\u093e\u0924\u0947\u0964"]],variants:"\u0906\u092e \u0935\u093f\u0935\u093f\u0927\u0924\u093e\u090f\u0901 \u0917\u094d\u0930\u093f\u0921 \u0915\u093e \u0906\u0915\u093e\u0930 \u092c\u0926\u0932\u0924\u0940 \u0939\u0948\u0902 (\u091b\u094b\u091f\u0947 3x3 \u0938\u0947 \u0932\u0947\u0915\u0930 \u092c\u0921\u093c\u0947 \u092c\u094b\u0930\u094d\u0921 \u0924\u0915), \u0915\u094d\u0930\u092e \u092e\u0947\u0902 \u0915\u0908 \u092a\u0948\u091f\u0930\u094d\u0928 \u0926\u093f\u0916\u093e\u0924\u0940 \u0939\u0948\u0902, \u0938\u093f\u0930\u094d\u092b\u093c \u0938\u092e\u0942\u0939 \u0928\u0939\u0940\u0902 \u092c\u0932\u094d\u0915\u093f \u0915\u094b\u0936\u093f\u0915\u093e\u0913\u0902 \u0915\u0947 \u091c\u0932\u0928\u0947 \u0915\u093e \u0915\u094d\u0930\u092e \u0926\u094b\u0939\u0930\u093e\u0928\u0947 \u0915\u094b \u0915\u0939\u0924\u0940 \u0939\u0948\u0902, \u0927\u094d\u092f\u093e\u0928-\u092d\u091f\u0915\u093e\u0928\u0947 \u0935\u093e\u0932\u0940 \u091d\u0932\u0915\u0947\u0902 \u091c\u094b\u0921\u093c\u0924\u0940 \u0939\u0948\u0902, \u092f\u093e \u0906\u092a\u0915\u0947 \u091c\u0935\u093e\u092c \u092a\u0930 \u0938\u092e\u092f-\u0938\u0940\u092e\u093e \u0932\u0917\u093e \u0926\u0947\u0924\u0940 \u0939\u0948\u0902\u0964 \u0915\u0941\u091b \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0938\u094d\u092e\u0930\u0923 \u0915\u0920\u093f\u0928 \u092c\u0928\u093e\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u092a\u0948\u091f\u0930\u094d\u0928 \u0915\u094b \u0927\u0941\u0901\u0927\u0932\u093e \u092f\u093e \u0916\u093f\u0938\u0915\u093e \u0926\u0947\u0924\u0947 \u0939\u0948\u0902\u0964"},zh:{about:"\u300a\u8bb0\u5fc6\u77e9\u9635\u300b\u4f1a\u5c55\u793a\u4e00\u4e2a\u65b9\u683c\uff0c\u5176\u4e2d\u4e00\u4e9b\u683c\u5b50\u77ed\u6682\u5730\u4eae\u8d77\uff0c\u968f\u540e\u5f52\u4e8e\u7a7a\u767d\u3002\u4f60\u7684\u4efb\u52a1\u662f\u51ed\u8bb0\u5fc6\u590d\u73b0\u8fd9\u4e00\u56fe\u6848\uff0c\u51c6\u786e\u5730\u70b9\u6309\u90a3\u4e9b\u66fe\u7ecf\u4eae\u8fc7\u7684\u683c\u5b50\u3002\u968f\u7740\u8fdb\u7a0b\u63a8\u8fdb\uff0c\u65b9\u683c\u4f1a\u53d8\u5927\u3001\u56fe\u6848\u4f1a\u53d8\u5bc6\uff0c\u4e8e\u662f\u6bcf\u4e00\u8f6e\u90fd\u8981\u6c42\u4f60\u4e00\u6b21\u8bb0\u4f4f\u7a0d\u591a\u4e00\u70b9\u7684\u7a7a\u95f4\u4fe1\u606f\u3002",benefit:"\u5b83\u8bad\u7ec3\u89c6\u89c9\u7a7a\u95f4\u5de5\u4f5c\u8bb0\u5fc6\u548c\u77ed\u65f6\u7a7a\u95f4\u56de\u5fc6\uff0c\u5373\u628a\u82e5\u5e72\u6761\u76ee\u201c\u5728\u54ea\u91cc\u201d\u8fd9\u4e00\u4fe1\u606f\u5728\u8111\u4e2d\u4fdd\u6301\u51e0\u79d2\u949f\u7684\u80fd\u529b\u3002\u5b83\u4e5f\u4f9d\u8d56\u4e13\u6ce8\u7684\u6ce8\u610f\u529b\uff0c\u56e0\u4e3a\u5728\u56fe\u6848\u95ea\u73b0\u65f6\u4e00\u65e6\u8d70\u795e\uff0c\u6574\u8f6e\u5c31\u6ce1\u6c64\u4e86\u3002",history:"\u8fd9\u9879\u7ec3\u4e60\u662f\u795e\u7ecf\u5fc3\u7406\u5b66\u4e2d\u7ecf\u5178\u7a7a\u95f4\u5e7f\u5ea6\u6d4b\u9a8c\u7684\u6570\u5b57\u540e\u88d4\u3002\u8fd9\u79cd\u65b9\u683c-\u95ea\u73b0\u7684\u5f62\u5f0f\u5728 21 \u4e16\u7eaa\u5934\u5341\u5e74\u672b\u548c 2010 \u5e74\u4ee3\u88ab\u8111\u529b\u8bad\u7ec3\u5e94\u7528\u63a8\u5e7f\u7ed9\u5927\u4f17\uff0c\u5176\u4e2d Lumosity \u7684 Memory Matrix \u662f\u6700\u77e5\u540d\u7684\u7248\u672c\uff0c\u4e5f\u662f\u8fd9\u4e2a\u540d\u5b57\u7684\u51fa\u5904\u3002",creator:"\u5b83\u6ca1\u6709\u5355\u4e00\u7684\u53d1\u660e\u8005\u3002\u8fd9\u4e00\u5f62\u5f0f\u76f4\u63a5\u6e90\u81ea\u79d1\u897f\u65b9\u5757\u6572\u51fb\u6d4b\u9a8c\uff0c\u7531\u52a0\u62ff\u5927-\u610f\u5927\u5229\u7c4d\u5fc3\u7406\u5b66\u5bb6\u83f2\u5229\u666e\xb7\u79d1\u897f\uff08Philip Corsi\uff09\u4e8e 1972 \u81f3 1973 \u5e74\u524d\u540e\u8bbe\u8ba1\uff0c\u4f5c\u4e3a\u6570\u5b57\u5e7f\u5ea6\u7684\u7a7a\u95f4\u5bf9\u5e94\u7269\uff0c\u5e76\u627f\u63a5 D. O. Hebb \u65e9\u5148\u7684\u5de5\u4f5c\u3002\u591a\u6570\u4eba\u6240\u719f\u77e5\u7684\u90a3\u6b3e\u7cbe\u81f4\u65b9\u683c\u6e38\u620f\uff0c\u662f\u7531 Lumos Labs\uff08Lumosity\uff09\u6253\u9020\u5e76\u547d\u540d\u4e3a Memory Matrix \u7684\u3002",methods:"\u522b\u4e00\u4e2a\u4e00\u4e2a\u5730\u53bb\u8bb0\u683c\u5b50\u3002\u628a\u4eae\u8d77\u7684\u683c\u5b50\u5f52\u5e76\u6210\u5f62\u72b6\u3001\u7ebf\u6761\u548c\u7c07\u56e2\uff0c\u5e76\u7559\u610f\u5bf9\u89d2\u7ebf\u6216\u5bf9\u79f0\u3002\u8ba9\u89c6\u7ebf\u505c\u5728\u4e2d\u5fc3\u9644\u8fd1\uff0c\u4ee5\u4fbf\u4e00\u773c\u770b\u5230\u6574\u4e2a\u65b9\u683c\uff1b\u4e0e\u5176\u6570\u65b9\u683c\uff0c\u4e0d\u5982\u9ed8\u9ed8\u8bb0\u4e0b\u5927\u81f4\u7684\u4f4d\u7f6e\uff08\u5de6\u4e0a\u89d2\u3001\u4e2d\u95f4\u4e00\u884c\uff09\u3002\u628a\u96be\u5ea6\u5f80\u4e0a\u63a8\uff0c\u76f4\u5230\u4f60\u5927\u7ea6\u4e09\u5206\u4e4b\u4e00\u7684\u6b21\u6570\u4f1a\u5931\u8d25\u2014\u2014\u90a3\u4e2a\u8fb9\u754c\uff0c\u624d\u662f\u8bb0\u5fc6\u5e7f\u5ea6\u771f\u6b63\u5f97\u5230\u62c9\u4f38\u7684\u5730\u65b9\u3002",duration:"\u77ed\u65f6\u6bb5\u6700\u6709\u6548\uff1a\u4e94\u5230\u5341\u5206\u949f\u3001\u6bcf\u5468\u51e0\u6b21\u3001\u5168\u795e\u8d2f\u6ce8\uff0c\u80dc\u8fc7\u6f2b\u957f\u7684\u9a6c\u62c9\u677e\u3002\u7a7a\u95f4\u8bb0\u5fc6\u5f88\u5feb\u5c31\u4f1a\u75b2\u52b3\uff0c\u6240\u4ee5\u4e00\u65e6\u4f60\u7684\u51c6\u786e\u7387\u660e\u663e\u4e0b\u6ed1\uff0c\u5c31\u505c\u4e0b\uff0c\u800c\u4e0d\u8981\u786c\u6491\u7740\u71ac\u8fc7\u75b2\u52b3\u3002",research:"\u8bc1\u636e\u6700\u5145\u5206\u7684\u6070\u6070\u662f\u4f60\u80fd\u9884\u6599\u5230\u7684\u90e8\u5206\u2014\u2014\u4f60\u4f1a\u66f4\u64c5\u957f\u8bb0\u5fc6\u65b9\u683c\u56fe\u6848\uff0c\u4ee5\u53ca\u7c7b\u4f3c\u7684\u7a7a\u95f4\u5e7f\u5ea6\u4efb\u52a1\u3002\u66f4\u5bbd\u6cdb\u7684\u627f\u8bfa\u5219\u8981\u8584\u5f31\u5f97\u591a\uff1a\u5de5\u4f5c\u8bb0\u5fc6\u8bad\u7ec3\u7684\u5143\u5206\u6790\uff0c\u5305\u62ec Melby-Lerv\xe5g \u548c Hulme \u90a3\u7bc7\u5e7f\u53d7\u5f15\u7528\u7684 2016 \u5e74\u7efc\u8ff0\uff0c\u51e0\u4e4e\u627e\u4e0d\u5230\u53ef\u9760\u7684\u3001\u5411\u6574\u4f53\u667a\u529b\u3001\u5b66\u4e1a\u8868\u73b0\u6216\u65e5\u5e38\u8bb0\u5fc6\u7684\u8fdc\u8fc1\u79fb\u3002Lumosity \u81ea\u5df1\u4e5f\u66fe\u5728 2016 \u5e74\u56e0\u7f3a\u4e4f\u4f9d\u636e\u7684\u8111\u529b\u8bad\u7ec3\u5ba3\u4f20\uff0c\u5411\u7f8e\u56fd\u8054\u90a6\u8d38\u6613\u59d4\u5458\u4f1a\u652f\u4ed8\u4e86 200 \u4e07\u7f8e\u5143\u548c\u89e3\u91d1\uff0c\u6240\u4ee5\u5bf9\u4efb\u4f55\u201c\u63d0\u5347\u667a\u5546\u201d\u6216\u201c\u9884\u9632\u8870\u9000\u201d\u7684\u8bf4\u8f9e\uff0c\u90fd\u8981\u62b1\u4ee5\u771f\u6b63\u7684\u8c28\u614e\u3002",rec:"\u628a\u5b83\u5f53\u4f5c\u78e8\u783a\u7a7a\u95f4\u6ce8\u610f\u529b\u7684\u4e13\u6ce8\u70ed\u8eab\uff0c\u800c\u975e\u5065\u5fd8\u75c7\u7684\u89e3\u836f\uff1b\u4ee5\u4f60\u81ea\u5df1\u7684\u5e7f\u5ea6\u5728\u6570\u5468\u5185\u7684\u589e\u957f\u6765\u8bc4\u5224\u8fdb\u6b65\uff0c\u800c\u4e0d\u662f\u4ee5\u90a3\u4e9b\u5173\u4e8e\u201c\u6d3b\u5f97\u66f4\u806a\u660e\u201d\u7684\u8bf4\u6cd5\u3002",faq:[["\u8bb0\u5fc6\u77e9\u9635\u4f1a\u8ba9\u6211\u73b0\u5b9e\u751f\u6d3b\u4e2d\u7684\u8bb0\u5fc6\u53d8\u597d\u5417\uff1f","\u5b83\u80fd\u53ef\u9760\u5730\u63d0\u5347\u4f60\u5728\u8fd9\u7c7b\u53ca\u7c7b\u4f3c\u65b9\u683c\u4efb\u52a1\u4e0a\u7684\u8868\u73b0\uff0c\u4f46\u7814\u7a76\u5e76\u4e0d\u652f\u6301\u5b83\u80fd\u5e7f\u6cdb\u5730\u63d0\u5347\u65e5\u5e38\u8bb0\u5fc6\u6216\u667a\u529b\u3002\u8bf7\u628a\u5b83\u5f53\u4f5c\u9488\u5bf9\u7a7a\u95f4\u56de\u5fc6\u7684\u4e13\u9879\u953b\u70bc\uff0c\u800c\u975e\u4e00\u6b21\u5168\u9762\u5347\u7ea7\u3002"],["\u8fd9\u548c\u666e\u901a\u7684\u7ffb\u724c\u914d\u5bf9\u8bb0\u5fc6\u6e38\u620f\u6709\u4ec0\u4e48\u4e0d\u540c\uff1f","\u914d\u5bf9\u6e38\u620f\uff08\u5982\u201c\u4e13\u6ce8\u529b\u201d\u7ffb\u724c\uff09\u662f\u901a\u8fc7\u591a\u6b21\u7ffb\u52a8\u3001\u53cd\u590d\u8bd5\u9519\u6765\u8003\u9a8c\u201c\u54ea\u4e2a\u7b26\u53f7\u5728\u54ea\u91cc\u201d\u3002\u8bb0\u5fc6\u77e9\u9635\u5219\u628a\u5b8c\u6574\u56fe\u6848\u5c55\u793a\u4e00\u6b21\uff0c\u518d\u8981\u6c42\u4f60\u51ed\u8fd9\u4e00\u773c\u77ed\u6682\u7684\u89c2\u770b\u590d\u73b0\u5176\u786e\u5207\u4f4d\u7f6e\uff0c\u8fd9\u66f4\u76f4\u63a5\u5730\u8003\u9a8c\u7a7a\u95f4\u5de5\u4f5c\u8bb0\u5fc6\u3002"],["\u62ff\u9ad8\u5206\u6700\u597d\u7684\u529e\u6cd5\u662f\u4ec0\u4e48\uff1f","\u628a\u4eae\u8d77\u7684\u683c\u5b50\u5f52\u5e76\u6210\u5f62\u72b6\u548c\u7ebf\u6761\uff0c\u800c\u4e0d\u662f\u53bb\u8bb0\u5355\u4e2a\u65b9\u683c\uff1b\u8ba9\u89c6\u7ebf\u505c\u5728\u4e2d\u5fc3\u9644\u8fd1\uff0c\u4ee5\u4fbf\u628a\u6574\u4e2a\u65b9\u683c\u5c3d\u6536\u773c\u5e95\uff1b\u5e76\u505c\u7559\u5728\u4e00\u4e2a\u8ba9\u4f60\u5931\u8d25\u5f97\u8db3\u591f\u9891\u7e41\u3001\u56e0\u800c\u5177\u6709\u6311\u6218\u7684\u96be\u5ea6\u4e0a\u3002\u8f7b\u677e\u8fc7\u5173\u7684\u56de\u5408\u51e0\u4e4e\u7ec3\u4e0d\u5230\u4ec0\u4e48\u3002"]],variants:"\u5e38\u89c1\u7684\u53d8\u4f53\u4f1a\u6539\u53d8\u65b9\u683c\u5927\u5c0f\uff08\u4ece\u5c0f\u7684 3\xd73 \u5230\u5927\u578b\u68cb\u76d8\uff09\uff0c\u4f1a\u4f9d\u6b21\u5c55\u793a\u6570\u4e2a\u56fe\u6848\uff0c\u4f1a\u8981\u6c42\u4f60\u590d\u73b0\u683c\u5b50\u4eae\u8d77\u7684\u987a\u5e8f\u800c\u4e0d\u4ec5\u662f\u90a3\u4e00\u7ec4\uff0c\u4f1a\u52a0\u5165\u5e72\u6270\u6027\u95ea\u70c1\uff0c\u6216\u5bf9\u4f60\u7684\u4f5c\u7b54\u8bbe\u7f6e\u65f6\u95f4\u9650\u5236\u3002\u67d0\u4e9b\u7248\u672c\u4f1a\u8ba9\u56fe\u6848\u6de1\u51fa\u6216\u79fb\u52a8\uff0c\u4ee5\u52a0\u5927\u56de\u5fc6\u96be\u5ea6\u3002"}},"mental-rotation":{ru:{about:"\u0412 \xab\u041c\u044b\u0441\u043b\u0435\u043d\u043d\u043e\u043c \u0432\u0440\u0430\u0449\u0435\u043d\u0438\u0438\xbb \u0432\u0430\u043c \u043f\u043e\u043a\u0430\u0437\u044b\u0432\u0430\u044e\u0442 \u0434\u0432\u0430 \u043e\u0431\u044a\u0435\u043a\u0442\u0430 \u2014 \u043e\u0431\u044b\u0447\u043d\u043e \u0444\u0438\u0433\u0443\u0440\u044b \u0438\u0437 \u043a\u0443\u0431\u0438\u043a\u043e\u0432 \u0438\u043b\u0438 \u043f\u043b\u043e\u0441\u043a\u0443\u044e \u0444\u043e\u0440\u043c\u0443 \u0438 \u0435\u0451 \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u044b \u2014 \u0438 \u0437\u0430\u0434\u0430\u044e\u0442 \u043e\u0434\u0438\u043d \u0432\u043e\u043f\u0440\u043e\u0441: \u044d\u0442\u043e \u0442\u043e\u0442 \u0436\u0435 \u043e\u0431\u044a\u0435\u043a\u0442, \u043f\u0440\u043e\u0441\u0442\u043e \u043f\u043e\u0432\u0451\u0440\u043d\u0443\u0442\u044b\u0439 \u0432 \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435, \u0438\u043b\u0438 \u0435\u0433\u043e \u0437\u0435\u0440\u043a\u0430\u043b\u044c\u043d\u043e\u0435 \u043e\u0442\u0440\u0430\u0436\u0435\u043d\u0438\u0435? \u0412\u0440\u0430\u0449\u0430\u0442\u044c \u043d\u0443\u0436\u043d\u043e \u0432 \u0443\u043c\u0435, \u0430 \u043d\u0435 \u043d\u0430 \u044d\u043a\u0440\u0430\u043d\u0435, \u0438 \u043a\u0430\u043a \u043c\u043e\u0436\u043d\u043e \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u043d\u0430\u0436\u0430\u0442\u044c \xab\u0441\u043e\u0432\u043f\u0430\u0434\u0430\u0435\u0442\xbb \u0438\u043b\u0438 \xab\u043d\u0435\u0442\xbb.",benefit:"\u0423\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u0435 \u0440\u0430\u0437\u0432\u0438\u0432\u0430\u0435\u0442 \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0435 \u0432\u043e\u043e\u0431\u0440\u0430\u0436\u0435\u043d\u0438\u0435 \u2014 \u0443\u043c\u0435\u043d\u0438\u0435 \u0443\u0434\u0435\u0440\u0436\u0430\u0442\u044c \u0444\u043e\u0440\u043c\u0443 \u0432 \u0433\u043e\u043b\u043e\u0432\u0435 \u0438 \u043c\u044b\u0441\u043b\u0435\u043d\u043d\u043e \u0435\u0451 \u043f\u0440\u0435\u043e\u0431\u0440\u0430\u0437\u043e\u0432\u0430\u0442\u044c: \u043f\u043e\u0432\u0435\u0440\u043d\u0443\u0442\u044c \u0438 \u0441\u0440\u0430\u0432\u043d\u0438\u0442\u044c \u0441 \u0434\u0440\u0443\u0433\u043e\u0439. \u042d\u0442\u043e \u0438 \u0435\u0441\u0442\u044c \u043e\u0441\u043d\u043e\u0432\u0430 \u0442\u043e\u0433\u043e, \u0447\u0442\u043e \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438 \u043d\u0430\u0437\u044b\u0432\u0430\u044e\u0442 \u043c\u044b\u0441\u043b\u0435\u043d\u043d\u044b\u043c \u0432\u0440\u0430\u0449\u0435\u043d\u0438\u0435\u043c, \u043e\u0434\u043d\u043e\u0433\u043e \u0438\u0437 \u0441\u0430\u043c\u044b\u0445 \u0438\u0437\u0443\u0447\u0435\u043d\u043d\u044b\u0445 \u043a\u043e\u043c\u043f\u043e\u043d\u0435\u043d\u0442\u043e\u0432 \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0433\u043e \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442\u0430.",history:"\u0417\u0430\u0434\u0430\u0447\u0430 \u0432\u044b\u0440\u043e\u0441\u043b\u0430 \u0438\u0437 \u043e\u0434\u043d\u043e\u0433\u043e \u0437\u043d\u0430\u043c\u0435\u043d\u0438\u0442\u043e\u0433\u043e \u044d\u043a\u0441\u043f\u0435\u0440\u0438\u043c\u0435\u043d\u0442\u0430 1971 \u0433\u043e\u0434\u0430 \u0438 \u0441\u0442\u0430\u043b\u0430 \u0440\u0430\u0431\u043e\u0447\u0438\u043c \u0438\u043d\u0441\u0442\u0440\u0443\u043c\u0435\u043d\u0442\u043e\u043c \u043a\u043e\u0433\u043d\u0438\u0442\u0438\u0432\u043d\u043e\u0439 \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u0438. \u0412 1978 \u0433\u043e\u0434\u0443 \u0412\u0430\u043d\u0434\u0435\u043d\u0431\u0435\u0440\u0433 \u0438 \u041a\u044c\u044e\u0437 \u043f\u0440\u0435\u0432\u0440\u0430\u0442\u0438\u043b\u0438 \u0438\u0441\u0445\u043e\u0434\u043d\u044b\u0435 \u0444\u0438\u0433\u0443\u0440\u044b \u0432 \u0431\u0443\u043c\u0430\u0436\u043d\u044b\u0439 \u0433\u0440\u0443\u043f\u043f\u043e\u0432\u043e\u0439 \u0442\u0435\u0441\u0442, \u0438 \u0447\u0435\u0440\u0435\u0437 \u043d\u0435\u0433\u043e \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u0435 \u0440\u0430\u0437\u043e\u0448\u043b\u043e\u0441\u044c \u043f\u043e \u0448\u043a\u043e\u043b\u0430\u043c, \u043b\u0430\u0431\u043e\u0440\u0430\u0442\u043e\u0440\u0438\u044f\u043c \u0438 \u043f\u0440\u043e\u0444\u043e\u0442\u0431\u043e\u0440\u0443; \u0441\u0435\u0433\u043e\u0434\u043d\u044f \u044d\u0442\u043e \u0441\u0442\u0430\u043d\u0434\u0430\u0440\u0442\u043d\u0430\u044f \u043f\u0440\u043e\u0431\u0430 \u0432 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u044f\u0445 \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0445 \u0441\u043f\u043e\u0441\u043e\u0431\u043d\u043e\u0441\u0442\u0435\u0439 \u0438 \u043f\u043e\u043b\u043e\u0432\u044b\u0445 \u0440\u0430\u0437\u043b\u0438\u0447\u0438\u0439.",creator:"\u0410\u0432\u0442\u043e\u0440\u044b \u2014 \u0420\u043e\u0434\u0436\u0435\u0440 \u0428\u0435\u043f\u0430\u0440\u0434 \u0438 \u0416\u0430\u043a\u043b\u0438\u043d \u041c\u0435\u0442\u0446\u043b\u0435\u0440, \u0447\u044c\u044f \u0441\u0442\u0430\u0442\u044c\u044f \xab\u041c\u044b\u0441\u043b\u0435\u043d\u043d\u043e\u0435 \u0432\u0440\u0430\u0449\u0435\u043d\u0438\u0435 \u0442\u0440\u0451\u0445\u043c\u0435\u0440\u043d\u044b\u0445 \u043e\u0431\u044a\u0435\u043a\u0442\u043e\u0432\xbb \u0432\u044b\u0448\u043b\u0430 \u0432 \u0436\u0443\u0440\u043d\u0430\u043b\u0435 Science \u0432 1971 \u0433\u043e\u0434\u0443. \u041e\u043d\u0438 \u043e\u0431\u043d\u0430\u0440\u0443\u0436\u0438\u043b\u0438, \u0447\u0442\u043e \u0432\u0440\u0435\u043c\u044f \u043d\u0430 \u0440\u0435\u0448\u0435\u043d\u0438\u0435 \u0440\u0430\u0441\u0442\u0451\u0442 \u043f\u0440\u043e\u043f\u043e\u0440\u0446\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u043e \u0443\u0433\u043b\u0443 \u043c\u0435\u0436\u0434\u0443 \u0444\u0438\u0433\u0443\u0440\u0430\u043c\u0438 \u2014 \u0431\u0443\u0434\u0442\u043e \u0440\u0430\u0437\u0443\u043c \u0438 \u0432\u043f\u0440\u0430\u0432\u0434\u0443 \u0432\u0440\u0430\u0449\u0430\u0435\u0442 \u043e\u0431\u0440\u0430\u0437 \u0441 \u043f\u043e\u0441\u0442\u043e\u044f\u043d\u043d\u043e\u0439 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c\u044e.",methods:"\u0412\u044b\u0431\u0435\u0440\u0438\u0442\u0435 \u043d\u0430 \u0444\u0438\u0433\u0443\u0440\u0435 \u043e\u043f\u043e\u0440\u043d\u0443\u044e \u0442\u043e\u0447\u043a\u0443 \u2014 \u0445\u0430\u0440\u0430\u043a\u0442\u0435\u0440\u043d\u044b\u0439 \u043e\u0442\u0440\u043e\u0441\u0442\u043e\u043a \u0438\u043b\u0438 \u0443\u0433\u043e\u043b \u2014 \u0438 \u0441\u043b\u0435\u0434\u0438\u0442\u0435, \u043a\u0443\u0434\u0430 \u043e\u043d\u0430 \u043f\u043e\u043f\u0430\u0434\u0451\u0442 \u043f\u0440\u0438 \u043f\u043e\u0432\u043e\u0440\u043e\u0442\u0435 \u0432\u0441\u0435\u0439 \u0444\u043e\u0440\u043c\u044b, \u0430 \u043d\u0435 \u043f\u0435\u0440\u0435\u0440\u0438\u0441\u043e\u0432\u044b\u0432\u0430\u0439\u0442\u0435 \u0435\u0451 \u043f\u043e \u043a\u0443\u0441\u043a\u0430\u043c. \u0412\u0440\u0430\u0449\u0430\u0439\u0442\u0435 \u043f\u043e \u043a\u0440\u0430\u0442\u0447\u0430\u0439\u0448\u0435\u043c\u0443 \u043f\u0443\u0442\u0438 \u043a \u043d\u0443\u0436\u043d\u043e\u043c\u0443 \u0443\u0433\u043b\u0443, \u0430 \u043f\u043e\u043d\u0430\u0447\u0430\u043b\u0443 \u043f\u0440\u043e\u0433\u043e\u0432\u0430\u0440\u0438\u0432\u0430\u0439\u0442\u0435 \u043d\u0430\u043f\u0440\u0430\u0432\u043b\u0435\u043d\u0438\u0435 \u0432\u0441\u043b\u0443\u0445 (\xab\u043d\u0430\u043a\u043b\u043e\u043d\u0438\u0442\u044c \u043d\u0430\u0437\u0430\u0434, \u043f\u043e\u0442\u043e\u043c \u0432\u043b\u0435\u0432\u043e\xbb), \u043f\u0440\u0435\u0436\u0434\u0435 \u0447\u0435\u043c \u0434\u043e\u0432\u0435\u0440\u0438\u0442\u044c\u0441\u044f \u043d\u0435\u043c\u043e\u043c\u0443 \u043e\u0431\u0440\u0430\u0437\u0443. \u0413\u043d\u0430\u0442\u044c\u0441\u044f \u0437\u0430 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c\u044e \u0441\u0442\u043e\u0438\u0442 \u043b\u0438\u0448\u044c \u043a\u043e\u0433\u0434\u0430 \u0432\u044b \u0441\u0442\u0430\u0431\u0438\u043b\u044c\u043d\u043e \u043e\u0442\u0432\u0435\u0447\u0430\u0435\u0442\u0435 \u0432\u0435\u0440\u043d\u043e.",duration:"\u041b\u0443\u0447\u0448\u0435 \u0432\u0441\u0435\u0433\u043e \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u0435 \u0447\u0430\u0441\u0442\u044b\u0435 \u043f\u043e\u0434\u0445\u043e\u0434\u044b: 10\u201315 \u043c\u0438\u043d\u0443\u0442, \u0442\u0440\u0438-\u043f\u044f\u0442\u044c \u0440\u0430\u0437 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e. \u041c\u044b\u0441\u043b\u0435\u043d\u043d\u043e\u0435 \u0432\u0440\u0430\u0449\u0435\u043d\u0438\u0435 \u0441\u0438\u043b\u044c\u043d\u043e \u043d\u0430\u0433\u0440\u0443\u0436\u0430\u0435\u0442 \u0440\u0430\u0431\u043e\u0447\u0443\u044e \u043f\u0430\u043c\u044f\u0442\u044c, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u043e\u0441\u0442\u0430\u043d\u0430\u0432\u043b\u0438\u0432\u0430\u0439\u0442\u0435\u0441\u044c, \u043a\u043e\u0433\u0434\u0430 \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u044c \u043d\u0430\u0447\u0438\u043d\u0430\u0435\u0442 \u043f\u0430\u0434\u0430\u0442\u044c, \u0430 \u043d\u0435 \u043f\u0440\u043e\u0434\u0430\u0432\u043b\u0438\u0432\u0430\u0439\u0442\u0435 \u0443\u0441\u0442\u0430\u043b\u043e\u0441\u0442\u044c.",research:"\u041d\u0430\u0434\u0451\u0436\u043d\u0435\u0435 \u0432\u0441\u0435\u0433\u043e \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u0435\u0442\u0441\u044f \u0440\u043e\u0432\u043d\u043e \u0442\u043e, \u0447\u0435\u0433\u043e \u0438 \u0436\u0434\u0451\u0448\u044c: \u0432\u044b \u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u0435\u0441\u044c \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u0438 \u0442\u043e\u0447\u043d\u0435\u0435 \u0432 \u0441\u0430\u043c\u043e\u043c \u043c\u044b\u0441\u043b\u0435\u043d\u043d\u043e\u043c \u0432\u0440\u0430\u0449\u0435\u043d\u0438\u0438, \u0430 \u043a\u0440\u0443\u043f\u043d\u044b\u0439 \u043c\u0435\u0442\u0430\u0430\u043d\u0430\u043b\u0438\u0437 2013 \u0433\u043e\u0434\u0430 \u043f\u043e 217 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u044f\u043c (\u0423\u0442\u0442\u0430\u043b \u0441 \u043a\u043e\u043b\u043b\u0435\u0433\u0430\u043c\u0438) \u043f\u043e\u043a\u0430\u0437\u0430\u043b, \u0447\u0442\u043e \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u0430\u044f \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0430 \u0443\u0441\u0442\u043e\u0439\u0447\u0438\u0432\u043e \u043f\u043e\u0432\u044b\u0448\u0430\u0435\u0442 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442\u044b \u0432 \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0445 \u0442\u0435\u0441\u0442\u0430\u0445, \u043f\u0440\u0438\u0447\u0451\u043c \u044d\u0444\u0444\u0435\u043a\u0442 \u043c\u043e\u0436\u0435\u0442 \u0441\u043e\u0445\u0440\u0430\u043d\u044f\u0442\u044c\u0441\u044f \u0438 \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0438\u0442\u044c\u0441\u044f \u043d\u0430 \u043f\u043e\u0445\u043e\u0436\u0438\u0435 \u0437\u0430\u0434\u0430\u0447\u0438. \u041e\u0442\u0434\u0435\u043b\u044c\u043d\u044b\u0435 \u0440\u0430\u0431\u043e\u0442\u044b, \u043d\u0430\u043f\u0440\u0438\u043c\u0435\u0440 \u0424\u044d\u043d\u0430, \u0421\u043f\u0435\u043d\u0441\u0430 \u0438 \u041f\u0440\u0430\u0442\u0442\u0430 (2007), \u0434\u0430\u0436\u0435 \u043e\u0442\u043c\u0435\u0442\u0438\u043b\u0438, \u0447\u0442\u043e \u044d\u043a\u0448\u0435\u043d-\u0438\u0433\u0440\u044b \u0441\u043e\u043a\u0440\u0430\u0449\u0430\u044e\u0442 \u043f\u0440\u0438\u0432\u044b\u0447\u043d\u044b\u0439 \u0440\u0430\u0437\u0440\u044b\u0432 \u043c\u0435\u0436\u0434\u0443 \u043f\u043e\u043b\u0430\u043c\u0438. \u041d\u043e \u0431\u043e\u043b\u0435\u0435 \u0433\u0440\u043e\u043c\u043a\u0438\u0435 \u0437\u0430\u044f\u0432\u043b\u0435\u043d\u0438\u044f \u2014 \u0447\u0442\u043e \u044d\u0442\u043e \u043f\u043e\u0434\u043d\u0438\u043c\u0430\u0435\u0442 \u043e\u0431\u0449\u0438\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0438\u043b\u0438 \u043d\u0430\u0434\u0451\u0436\u043d\u043e \u0443\u043b\u0443\u0447\u0448\u0430\u0435\u0442 \u043c\u0430\u0442\u0435\u043c\u0430\u0442\u0438\u043a\u0443 \u0438 \u0442\u043e\u0447\u043d\u044b\u0435 \u043d\u0430\u0443\u043a\u0438 \u2014 \u0441\u043b\u0430\u0431\u0435\u0435 \u0438 \u0441\u043f\u043e\u0440\u043d\u044b, \u0442\u0430\u043a \u0447\u0442\u043e \u0434\u0430\u043b\u044c\u043d\u0438\u0439 \u043f\u0435\u0440\u0435\u043d\u043e\u0441 \u0441\u0447\u0438\u0442\u0430\u0439\u0442\u0435 \u0432\u043e\u0437\u043c\u043e\u0436\u043d\u043e\u0441\u0442\u044c\u044e, \u0430 \u043d\u0435 \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u0435\u043c.",rec:"\u0421\u0431\u0430\u0432\u044c\u0442\u0435 \u0442\u0435\u043c\u043f \u0438 \u0441\u043d\u0430\u0447\u0430\u043b\u0430 \u0434\u043e\u0431\u0438\u0432\u0430\u0439\u0442\u0435\u0441\u044c \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u0438: \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u0431\u0435\u0441\u043f\u043e\u043b\u0435\u0437\u043d\u0430, \u0435\u0441\u043b\u0438 \u0432\u044b \u0443\u0432\u0435\u0440\u0435\u043d\u043d\u043e \u043d\u0430\u0437\u044b\u0432\u0430\u0435\u0442\u0435 \u0437\u0435\u0440\u043a\u0430\u043b\u044c\u043d\u044b\u0435 \u0444\u0438\u0433\u0443\u0440\u044b \u043e\u0434\u0438\u043d\u0430\u043a\u043e\u0432\u044b\u043c\u0438.",faq:[["\u041f\u043e\u0447\u0435\u043c\u0443 \u0431\u043e\u043b\u044c\u0448\u0438\u0435 \u043f\u043e\u0432\u043e\u0440\u043e\u0442\u044b \u0434\u0430\u044e\u0442\u0441\u044f \u0437\u0430\u043c\u0435\u0442\u043d\u043e \u043c\u0435\u0434\u043b\u0435\u043d\u043d\u0435\u0435?","\u041f\u043e\u0442\u043e\u043c\u0443 \u0447\u0442\u043e \u0432\u044b \u043a\u0430\u043a \u0431\u044b \u043f\u0440\u043e\u043a\u0440\u0443\u0447\u0438\u0432\u0430\u0435\u0442\u0435 \u043e\u0431\u044a\u0435\u043a\u0442 \u0432 \u0443\u043c\u0435 \u0441 \u043f\u0440\u0438\u043c\u0435\u0440\u043d\u043e \u043f\u043e\u0441\u0442\u043e\u044f\u043d\u043d\u043e\u0439 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c\u044e, \u0438 \u0431\u043e\u043b\u044c\u0448\u0438\u0439 \u0443\u0433\u043e\u043b \u043f\u0440\u043e\u0441\u0442\u043e \u0442\u0440\u0435\u0431\u0443\u0435\u0442 \u0431\u043e\u043b\u0435\u0435 \u0434\u043e\u043b\u0433\u043e\u0433\u043e \u043c\u044b\u0441\u043b\u0435\u043d\u043d\u043e\u0433\u043e \u043f\u0443\u0442\u0438. \u0428\u0435\u043f\u0430\u0440\u0434 \u0438 \u041c\u0435\u0442\u0446\u043b\u0435\u0440 \u0438\u043c\u0435\u043d\u043d\u043e \u044d\u0442\u043e \u0438 \u0438\u0437\u043c\u0435\u0440\u0438\u043b\u0438 \u2014 \u0432\u0440\u0435\u043c\u044f \u043e\u0442\u0432\u0435\u0442\u0430 \u0440\u0430\u0441\u0442\u0451\u0442 \u043f\u043e\u0447\u0442\u0438 \u043b\u0438\u043d\u0435\u0439\u043d\u043e \u0441 \u0443\u0433\u043b\u043e\u043c."],["\u042f \u043f\u043e\u0441\u0442\u043e\u044f\u043d\u043d\u043e \u043f\u0440\u0438\u043d\u0438\u043c\u0430\u044e \u0437\u0435\u0440\u043a\u0430\u043b\u044c\u043d\u044b\u0435 \u0444\u0438\u0433\u0443\u0440\u044b \u0437\u0430 \u0441\u043e\u0432\u043f\u0430\u0434\u0430\u044e\u0449\u0438\u0435. \u042d\u0442\u043e \u043d\u043e\u0440\u043c\u0430\u043b\u044c\u043d\u043e?","\u0414\u0430, \u0437\u0435\u0440\u043a\u0430\u043b\u044c\u043d\u044b\u0435 \u043f\u0430\u0440\u044b \u2014 \u043a\u043b\u0430\u0441\u0441\u0438\u0447\u0435\u0441\u043a\u0430\u044f \u043b\u043e\u0432\u0443\u0448\u043a\u0430, \u043f\u043e\u0442\u043e\u043c\u0443 \u0447\u0442\u043e \u0432\u044b\u0433\u043b\u044f\u0434\u044f\u0442 \u043e\u0434\u0438\u043d\u0430\u043a\u043e\u0432\u043e, \u043f\u043e\u043a\u0430 \u043d\u0435 \u043f\u0440\u043e\u0432\u0435\u0440\u0438\u0448\u044c \xab\u043f\u0440\u0430\u0432\u0443\u044e \u0438 \u043b\u0435\u0432\u0443\u044e \u0440\u0443\u043a\u0443\xbb. \u0417\u0430\u0446\u0435\u043f\u0438\u0442\u0435\u0441\u044c \u0437\u0430 \u043e\u0434\u043d\u0443 \u043d\u0435\u0441\u0438\u043c\u043c\u0435\u0442\u0440\u0438\u0447\u043d\u0443\u044e \u0434\u0435\u0442\u0430\u043b\u044c \u0438 \u0441\u043c\u043e\u0442\u0440\u0438\u0442\u0435, \u043e\u043a\u0430\u0436\u0435\u0442\u0441\u044f \u043b\u0438 \u043e\u043d\u0430 \u0441 \u043d\u0443\u0436\u043d\u043e\u0439 \u0441\u0442\u043e\u0440\u043e\u043d\u044b \u2014 \u044d\u0442\u043e \u0438 \u043e\u0442\u043b\u0438\u0447\u0430\u0435\u0442 \u043d\u0430\u0441\u0442\u043e\u044f\u0449\u0438\u0439 \u043f\u043e\u0432\u043e\u0440\u043e\u0442 \u043e\u0442 \u043e\u0442\u0440\u0430\u0436\u0435\u043d\u0438\u044f."],["\u0421\u0442\u0430\u043d\u0443 \u043b\u0438 \u044f \u043b\u0443\u0447\u0448\u0435 \u0447\u0438\u0442\u0430\u0442\u044c \u043a\u0430\u0440\u0442\u044b \u0438\u043b\u0438 \u043f\u0430\u0440\u043a\u043e\u0432\u0430\u0442\u044c\u0441\u044f?","\u0412\u044b \u043d\u0430\u0432\u0435\u0440\u043d\u044f\u043a\u0430 \u0441\u0442\u0430\u043d\u0435\u0442\u0435 \u043b\u0443\u0447\u0448\u0435 \u0432 \u0441\u0430\u043c\u043e\u043c \u043c\u044b\u0441\u043b\u0435\u043d\u043d\u043e\u043c \u0432\u0440\u0430\u0449\u0435\u043d\u0438\u0438 \u0438 \u043f\u043e\u0445\u043e\u0436\u0438\u0445 \u0442\u0435\u0441\u0442\u0430\u0445; \u043f\u0435\u0440\u0435\u043d\u0435\u0441\u0451\u0442\u0441\u044f \u043b\u0438 \u044d\u0442\u043e \u043d\u0430 \u0431\u044b\u0442\u043e\u0432\u044b\u0435 \u0437\u0430\u0434\u0430\u0447\u0438 \u0432\u0440\u043e\u0434\u0435 \u043e\u0440\u0438\u0435\u043d\u0442\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u044f \u0438\u043b\u0438 \u043f\u0430\u0440\u043a\u043e\u0432\u043a\u0438 \u2014 \u043f\u0440\u0430\u0432\u0434\u043e\u043f\u043e\u0434\u043e\u0431\u043d\u043e, \u043d\u043e \u0442\u043e\u043b\u043a\u043e\u043c \u043d\u0435 \u0434\u043e\u043a\u0430\u0437\u0430\u043d\u043e. \u0421\u0447\u0438\u0442\u0430\u0439\u0442\u0435 \u0432\u044b\u0438\u0433\u0440\u044b\u0448 \u0432 \u0436\u0438\u0437\u043d\u0438 \u043f\u0440\u0438\u044f\u0442\u043d\u044b\u043c \u0431\u043e\u043d\u0443\u0441\u043e\u043c, \u0430 \u043d\u0435 \u0433\u043b\u0430\u0432\u043d\u043e\u0439 \u043f\u0440\u0438\u0447\u0438\u043d\u043e\u0439 \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u0430\u0442\u044c\u0441\u044f."]],variants:"\u0411\u044b\u0432\u0430\u044e\u0442 \u043f\u043b\u043e\u0441\u043a\u0438\u0435 2D-\u0431\u0443\u043a\u0432\u044b \u0438 \u0444\u043e\u0440\u043c\u044b (\u043f\u043e\u043b\u0435\u0433\u0447\u0435) \u0438 \u0442\u0440\u0451\u0445\u043c\u0435\u0440\u043d\u044b\u0435 \u043a\u0443\u0431\u0438\u0447\u0435\u0441\u043a\u0438\u0435 \u0444\u0438\u0433\u0443\u0440\u044b \u043a\u0430\u043a \u0432 \u043e\u0440\u0438\u0433\u0438\u043d\u0430\u043b\u0435 (\u043f\u043e\u0442\u0440\u0443\u0434\u043d\u0435\u0435), \u0430 \u0442\u0430\u043a\u0436\u0435 \u0444\u043e\u0440\u043c\u0430\u0442 \xab\u0442\u0430 \u0436\u0435 \u0438\u043b\u0438 \u0437\u0435\u0440\u043a\u0430\u043b\u044c\u043d\u0430\u044f?\xbb \u043b\u0438\u0431\u043e \u0432\u044b\u0431\u043e\u0440 \u043f\u043e\u0432\u0451\u0440\u043d\u0443\u0442\u043e\u0439 \u043a\u043e\u043f\u0438\u0438 \u0438\u0437 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u0438\u0445 \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u043e\u0432. \u0421\u043b\u043e\u0436\u043d\u043e\u0441\u0442\u044c \u0440\u0430\u0441\u0442\u0451\u0442 \u0441 \u0443\u0433\u043b\u043e\u043c \u043f\u043e\u0432\u043e\u0440\u043e\u0442\u0430, \u0447\u0438\u0441\u043b\u043e\u043c \u043e\u0442\u0432\u043b\u0435\u043a\u0430\u044e\u0449\u0438\u0445 \u0444\u0438\u0433\u0443\u0440 \u0438 \u0442\u0435\u043c, \u0438\u0434\u0451\u0442 \u043b\u0438 \u0432\u0440\u0430\u0449\u0435\u043d\u0438\u0435 \u0432 \u043f\u043b\u043e\u0441\u043a\u043e\u0441\u0442\u0438 \u043a\u0430\u0440\u0442\u0438\u043d\u043a\u0438 \u0438\u043b\u0438 \u0432 \u0433\u043b\u0443\u0431\u0438\u043d\u0443."},en:{about:"Mental Rotation shows you two objects \u2014 usually shapes built from cubes or a flat figure and its variants \u2014 and asks one question: is the second one the same object simply turned in space, or a mirror image? You rotate it in your head, not on screen, and tap \"same\" or \"different\" as quickly as you can.",benefit:"It trains spatial visualisation \u2014 your ability to hold a shape in mind and transform it, rotating and comparing it against another. This is the core of what psychologists call mental rotation, one of the most studied components of spatial intelligence.",history:"The task grew straight out of a single famous 1971 experiment and became a workhorse of cognitive psychology. In 1978 Vandenberg and Kuse turned the original figures into a paper-and-pencil group test, which spread it into schools, labs and aptitude testing; today it is a standard screen in research on spatial ability and sex differences.",creator:"It comes from Roger N. Shepard and Jacqueline Metzler, whose paper \"Mental rotation of three-dimensional objects\" appeared in Science in 1971. They found that the time people need to decide two shapes match rises in proportion to the angle between them \u2014 as if the mind literally rotates an image at a steady speed.",methods:"Pick a fixed reference point on the object \u2014 a distinctive arm or corner \u2014 and track where it lands as you turn the whole shape, rather than redrawing it piece by piece. Rotate around the shortest path to the target angle, and at first say the direction out loud (\"tip it back, then turn left\") before trusting silent imagery. Push for speed only once you are reliably accurate.",duration:"Short, frequent sessions work best: 10 to 15 minutes, three to five times a week. Mental rotation is tiring to hold in working memory, so stop when accuracy starts to slip rather than grinding through fatigue.",research:"Evidence is strongest for exactly what you would expect \u2014 you get faster and more accurate at mental rotation itself, and a large 2013 meta-analysis of 217 studies (Uttal and colleagues) found spatial training reliably improves spatial test scores, with effects that can last and carry to similar tasks. Some studies, such as Feng, Spence and Pratt (2007), even found action video games narrowed the usual sex gap. But the bigger claims \u2014 that it lifts general intelligence or reliably boosts maths and STEM achievement \u2014 are weaker and contested, so treat far transfer as a possibility, not a promise.",rec:"Slow down and aim for accuracy first; speed is worthless if you are confidently calling mirror images \"the same\".",faq:[["Why do bigger rotations feel so much slower?","Because you are effectively spinning the object in your mind at a roughly constant rate, so a larger angle simply takes more mental travel. Shepard and Metzler measured exactly this \u2014 response time climbs almost linearly with the angle."],["I keep mistaking mirror images for matches. Is that normal?","Yes, mirrored pairs are the classic trap because they look identical until you check handedness. Lock onto one asymmetric feature and ask whether it ends up on the correct side \u2014 that distinguishes a true rotation from a reflection."],["Will this make me better at reading maps or parking a car?","It will reliably make you better at mental rotation and similar spatial tests; whether that carries over to everyday tasks like navigation or parking is plausible but not well proven. Treat real-world gains as a bonus, not the reason to train."]],variants:"Versions range from flat 2D letters or shapes (easier) to 3D cube figures like the originals (harder), and from \"same or mirrored?\" judgments to picking which of several options is the rotated match. Difficulty scales with the rotation angle, the number of distractors, and whether rotation happens in the picture plane or in depth."},es:{about:"Rotaci\xf3n Mental te muestra dos objetos \u2014normalmente figuras formadas por cubos, o una figura plana y sus variantes\u2014 y te plantea una sola pregunta: \xbfel segundo es el mismo objeto simplemente girado en el espacio, o una imagen especular? Lo rotas en tu cabeza, no en la pantalla, y tocas \"igual\" o \"diferente\" lo m\xe1s r\xe1pido que puedas.",benefit:"Entrena la visualizaci\xf3n espacial: tu capacidad de mantener una forma en mente y transformarla, rot\xe1ndola y compar\xe1ndola con otra. Esto es el n\xfacleo de lo que los psic\xf3logos llaman rotaci\xf3n mental, uno de los componentes m\xe1s estudiados de la inteligencia espacial.",history:"La tarea surgi\xf3 directamente de un \xfanico y famoso experimento de 1971 y se convirti\xf3 en un caballo de batalla de la psicolog\xeda cognitiva. En 1978 Vandenberg y Kuse transformaron las figuras originales en un test grupal de l\xe1piz y papel, lo que lo llev\xf3 a escuelas, laboratorios y pruebas de aptitud; hoy es una prueba est\xe1ndar en la investigaci\xf3n sobre capacidad espacial y diferencias de sexo.",creator:"Proviene de Roger N. Shepard y Jacqueline Metzler, cuyo art\xedculo \"Mental rotation of three-dimensional objects\" apareci\xf3 en Science en 1971. Descubrieron que el tiempo que necesita la gente para decidir si dos formas coinciden aumenta en proporci\xf3n al \xe1ngulo entre ellas, como si la mente literalmente rotara una imagen a velocidad constante.",methods:"Elige un punto de referencia fijo en el objeto \u2014un brazo o esquina distintivo\u2014 y sigue d\xf3nde acaba al girar la forma entera, en lugar de redibujarla pieza por pieza. Rota por el camino m\xe1s corto hasta el \xe1ngulo objetivo y, al principio, di la direcci\xf3n en voz alta (\"incl\xednalo hacia atr\xe1s, luego gira a la izquierda\") antes de fiarte de la imagen mental silenciosa. Busca velocidad solo cuando ya seas fiablemente preciso.",duration:"Las sesiones cortas y frecuentes funcionan mejor: de 10 a 15 minutos, de tres a cinco veces por semana. La rotaci\xf3n mental cansa mantenerla en la memoria de trabajo, as\xed que detente cuando la precisi\xf3n empiece a flaquear en lugar de forzar a trav\xe9s del cansancio.",research:"La evidencia es m\xe1s s\xf3lida justo para lo que cabr\xeda esperar: te vuelves m\xe1s r\xe1pido y preciso en la rotaci\xf3n mental en s\xed, y un amplio metaan\xe1lisis de 2013 de 217 estudios (Uttal y colaboradores) hall\xf3 que el entrenamiento espacial mejora de forma fiable las puntuaciones en tests espaciales, con efectos que pueden perdurar y trasladarse a tareas similares. Algunos estudios, como Feng, Spence y Pratt (2007), incluso encontraron que los videojuegos de acci\xf3n reduc\xedan la habitual brecha entre sexos. Pero las afirmaciones mayores \u2014que eleva la inteligencia general o que mejora de forma fiable el rendimiento en matem\xe1ticas y STEM\u2014 son m\xe1s d\xe9biles y discutidas, as\xed que toma la transferencia lejana como una posibilidad, no como una promesa.",rec:"Baja el ritmo y apunta primero a la precisi\xf3n; la velocidad no vale nada si est\xe1s llamando con seguridad \"iguales\" a im\xe1genes especulares.",faq:[["\xbfPor qu\xe9 las rotaciones m\xe1s grandes se sienten mucho m\xe1s lentas?","Porque en la pr\xe1ctica est\xe1s haciendo girar el objeto en tu mente a un ritmo m\xe1s o menos constante, as\xed que un \xe1ngulo mayor simplemente requiere m\xe1s recorrido mental. Shepard y Metzler midieron exactamente esto: el tiempo de respuesta sube de forma casi lineal con el \xe1ngulo."],["Sigo confundiendo im\xe1genes especulares con coincidencias. \xbfEs normal?","S\xed, los pares especulares son la trampa cl\xe1sica porque parecen id\xe9nticos hasta que compruebas la lateralidad. F\xedjate en un rasgo asim\xe9trico y preg\xfantate si acaba en el lado correcto: eso distingue una rotaci\xf3n real de un reflejo."],["\xbfEsto me har\xe1 mejor leyendo mapas o aparcando el coche?","Te har\xe1 mejor de forma fiable en la rotaci\xf3n mental y en tests espaciales similares; que eso se traslade a tareas cotidianas como orientarte o aparcar es plausible, pero no est\xe1 bien probado. Toma las ganancias en el mundo real como un extra, no como la raz\xf3n para entrenar."]],variants:"Las versiones van desde letras o formas planas en 2D (m\xe1s f\xe1cil) hasta figuras de cubos en 3D como las originales (m\xe1s dif\xedcil), y desde juicios de \"\xbfigual o especular?\" hasta elegir cu\xe1l de varias opciones es la coincidencia rotada. La dificultad escala con el \xe1ngulo de rotaci\xf3n, el n\xfamero de distractores y si la rotaci\xf3n ocurre en el plano de la imagen o en profundidad."},de:{about:"Mental Rotation zeigt dir zwei Objekte \u2014 meist aus W\xfcrfeln zusammengesetzte Formen oder eine flache Figur und ihre Varianten \u2014 und stellt eine einzige Frage: Ist das zweite dasselbe Objekt, nur im Raum gedreht, oder ein Spiegelbild? Du drehst es im Kopf, nicht auf dem Bildschirm, und tippst so schnell wie m\xf6glich auf \"gleich\" oder \"verschieden\".",benefit:"Es trainiert die r\xe4umliche Vorstellung \u2014 deine F\xe4higkeit, eine Form im Kopf zu behalten und sie zu transformieren, sie zu drehen und mit einer anderen zu vergleichen. Das ist der Kern dessen, was Psychologen mentale Rotation nennen, eine der am gr\xfcndlichsten untersuchten Komponenten der r\xe4umlichen Intelligenz.",history:"Die Aufgabe ging unmittelbar aus einem einzigen ber\xfchmten Experiment von 1971 hervor und wurde zum Arbeitspferd der kognitiven Psychologie. 1978 verwandelten Vandenberg und Kuse die urspr\xfcnglichen Figuren in einen Papier-und-Bleistift-Gruppentest, was sie in Schulen, Labore und Eignungstests trug; heute ist sie ein Standardinstrument in der Forschung zu r\xe4umlicher Begabung und Geschlechtsunterschieden.",creator:"Sie stammt von Roger N. Shepard und Jacqueline Metzler, deren Aufsatz \"Mental rotation of three-dimensional objects\" 1971 in Science erschien. Sie fanden heraus, dass die Zeit, die Menschen brauchen, um zu entscheiden, ob zwei Formen \xfcbereinstimmen, proportional zum Winkel zwischen ihnen ansteigt \u2014 als ob der Geist ein Bild buchst\xe4blich mit gleichm\xe4\xdfiger Geschwindigkeit dreht.",methods:"W\xe4hle einen festen Bezugspunkt am Objekt \u2014 einen markanten Arm oder eine markante Ecke \u2014 und verfolge, wo er landet, w\xe4hrend du die gesamte Form drehst, statt sie St\xfcck f\xfcr St\xfcck neu zu zeichnen. Drehe \xfcber den k\xfcrzesten Weg zum Zielwinkel, und sprich die Richtung anfangs laut aus (\"nach hinten kippen, dann nach links drehen\"), bevor du der stummen Vorstellung vertraust. Strebe erst dann nach Tempo, wenn du zuverl\xe4ssig genau bist.",duration:"Kurze, h\xe4ufige Einheiten funktionieren am besten: 10 bis 15 Minuten, drei- bis f\xfcnfmal pro Woche. Mentale Rotation ist anstrengend im Arbeitsged\xe4chtnis zu halten, also h\xf6r auf, wenn die Genauigkeit nachzulassen beginnt, statt dich durch die Ersch\xf6pfung zu qu\xe4len.",research:"Die Belege sind am st\xe4rksten f\xfcr genau das, was man erwarten w\xfcrde \u2014 du wirst schneller und genauer bei der mentalen Rotation selbst, und eine gro\xdfe Metaanalyse von 2013 \xfcber 217 Studien (Uttal und Kollegen) fand, dass r\xe4umliches Training die Werte in r\xe4umlichen Tests zuverl\xe4ssig verbessert, mit Effekten, die anhalten und auf \xe4hnliche Aufgaben \xfcbertragen k\xf6nnen. Einige Studien, etwa Feng, Spence und Pratt (2007), fanden sogar, dass Action-Videospiele die \xfcbliche Geschlechtskluft verringerten. Aber die gr\xf6\xdferen Behauptungen \u2014 dass es die allgemeine Intelligenz hebt oder Mathe- und MINT-Leistungen zuverl\xe4ssig steigert \u2014 sind schw\xe4cher und umstritten, also behandle fernen Transfer als M\xf6glichkeit, nicht als Versprechen.",rec:"Werde langsamer und ziele zuerst auf Genauigkeit; Tempo ist wertlos, wenn du Spiegelbilder selbstbewusst als \"gleich\" bezeichnest.",faq:[["Warum f\xfchlen sich gr\xf6\xdfere Drehungen so viel langsamer an?","Weil du das Objekt im Kopf praktisch mit ann\xe4hernd konstanter Rate drehst, sodass ein gr\xf6\xdferer Winkel schlicht mehr mentale Wegstrecke braucht. Shepard und Metzler haben genau das gemessen \u2014 die Reaktionszeit steigt fast linear mit dem Winkel."],["Ich verwechsle Spiegelbilder st\xe4ndig mit \xdcbereinstimmungen. Ist das normal?","Ja, gespiegelte Paare sind die klassische Falle, weil sie identisch aussehen, bis du die H\xe4ndigkeit pr\xfcfst. Fixiere dich auf ein asymmetrisches Merkmal und frage, ob es auf der richtigen Seite landet \u2014 das unterscheidet eine echte Drehung von einer Spiegelung."],["Werde ich dadurch besser im Kartenlesen oder Einparken?","Es macht dich zuverl\xe4ssig besser bei der mentalen Rotation und \xe4hnlichen r\xe4umlichen Tests; ob sich das auf Alltagsaufgaben wie Navigation oder Einparken \xfcbertr\xe4gt, ist plausibel, aber nicht gut belegt. Behandle reale Gewinne als Bonus, nicht als Grund zu trainieren."]],variants:"Die Versionen reichen von flachen 2D-Buchstaben oder -Formen (leichter) bis zu 3D-W\xfcrfelfiguren wie den Originalen (schwerer) und von \"gleich oder gespiegelt?\"-Urteilen bis zur Wahl, welche von mehreren Optionen die gedrehte Entsprechung ist. Der Schwierigkeitsgrad steigt mit dem Drehwinkel, der Anzahl der Ablenker und damit, ob die Drehung in der Bildebene oder in der Tiefe stattfindet."},pt:{about:"Rota\xe7\xe3o Mental mostra dois objetos \u2014 geralmente formas montadas com cubos ou uma figura plana e suas variantes \u2014 e faz uma \xfanica pergunta: o segundo \xe9 o mesmo objeto apenas girado no espa\xe7o, ou uma imagem espelhada? Voc\xea o gira na cabe\xe7a, n\xe3o na tela, e toca em \"igual\" ou \"diferente\" o mais r\xe1pido que conseguir.",benefit:"Ele treina a visualiza\xe7\xe3o espacial \u2014 sua capacidade de segurar uma forma na mente e transform\xe1-la, girando-a e comparando-a com outra. Isso \xe9 o cerne do que os psic\xf3logos chamam de rota\xe7\xe3o mental, um dos componentes mais estudados da intelig\xeancia espacial.",history:"A tarefa nasceu diretamente de um \xfanico e famoso experimento de 1971 e virou um cavalo de batalha da psicologia cognitiva. Em 1978, Vandenberg e Kuse transformaram as figuras originais num teste coletivo de papel e l\xe1pis, o que a levou para escolas, laborat\xf3rios e avalia\xe7\xf5es de aptid\xe3o; hoje ela \xe9 uma medida padr\xe3o em pesquisas sobre habilidade espacial e diferen\xe7as entre os sexos.",creator:"Vem de Roger N. Shepard e Jacqueline Metzler, cujo artigo \"Mental rotation of three-dimensional objects\" saiu na Science em 1971. Eles descobriram que o tempo que as pessoas precisam para decidir se duas formas coincidem cresce na propor\xe7\xe3o do \xe2ngulo entre elas \u2014 como se a mente literalmente girasse a imagem a uma velocidade constante.",methods:"Escolha um ponto de refer\xeancia fixo no objeto \u2014 um bra\xe7o ou um canto caracter\xedstico \u2014 e acompanhe onde ele vai parar ao girar a forma inteira, em vez de redesenh\xe1-la peda\xe7o por peda\xe7o. Gire pelo caminho mais curto at\xe9 o \xe2ngulo-alvo e, no come\xe7o, diga a dire\xe7\xe3o em voz alta (\"inclina para tr\xe1s, depois vira \xe0 esquerda\") antes de confiar na imagem silenciosa. S\xf3 busque velocidade quando j\xe1 estiver acertando de forma consistente.",duration:"Sess\xf5es curtas e frequentes funcionam melhor: de 10 a 15 minutos, de tr\xeas a cinco vezes por semana. A rota\xe7\xe3o mental \xe9 cansativa de manter na mem\xf3ria de trabalho, ent\xe3o pare quando a precis\xe3o come\xe7ar a cair em vez de insistir no cansa\xe7o.",research:"As evid\xeancias s\xe3o mais fortes exatamente para o esperado \u2014 voc\xea fica mais r\xe1pido e mais preciso na pr\xf3pria rota\xe7\xe3o mental, e uma grande metan\xe1lise de 2013, com 217 estudos (Uttal e colaboradores), constatou que o treino espacial melhora de forma confi\xe1vel as pontua\xe7\xf5es em testes espaciais, com efeitos que podem durar e se estender a tarefas semelhantes. Alguns estudos, como Feng, Spence e Pratt (2007), chegaram a constatar que videogames de a\xe7\xe3o reduziram a habitual diferen\xe7a entre os sexos. Mas as alega\xe7\xf5es maiores \u2014 de que isso eleva a intelig\xeancia geral ou aumenta de forma confi\xe1vel o desempenho em matem\xe1tica e nas \xe1reas STEM \u2014 s\xe3o mais fracas e contestadas, ent\xe3o encare a transfer\xeancia distante como uma possibilidade, n\xe3o como uma promessa.",rec:"V\xe1 com calma e busque precis\xe3o primeiro; velocidade n\xe3o vale nada se voc\xea est\xe1, com confian\xe7a, chamando imagens espelhadas de \"iguais\".",faq:[["Por que rota\xe7\xf5es maiores parecem t\xe3o mais lentas?","Porque voc\xea est\xe1, na pr\xe1tica, girando o objeto na mente a uma velocidade mais ou menos constante, ent\xe3o um \xe2ngulo maior simplesmente exige mais percurso mental. Shepard e Metzler mediram exatamente isso \u2014 o tempo de resposta sobe quase linearmente com o \xe2ngulo."],["Eu vivo confundindo imagens espelhadas com correspond\xeancias. Isso \xe9 normal?","Sim, os pares espelhados s\xe3o a armadilha cl\xe1ssica porque parecem id\xeanticos at\xe9 voc\xea checar a lateralidade. Fixe-se numa caracter\xedstica assim\xe9trica e pergunte se ela acaba do lado certo \u2014 \xe9 isso que distingue uma rota\xe7\xe3o verdadeira de um reflexo."],["Isso vai me deixar melhor em ler mapas ou estacionar o carro?","Vai te deixar de forma confi\xe1vel melhor em rota\xe7\xe3o mental e em testes espaciais parecidos; se isso se transfere para tarefas do dia a dia, como navega\xe7\xe3o ou estacionar, \xe9 plaus\xedvel, mas n\xe3o est\xe1 bem comprovado. Encare os ganhos no mundo real como um b\xf4nus, n\xe3o como o motivo para treinar."]],variants:"As vers\xf5es v\xe3o de letras ou formas planas em 2D (mais f\xe1ceis) a figuras de cubos em 3D como as originais (mais dif\xedceis), e de julgamentos do tipo \"igual ou espelhado?\" a escolher qual de v\xe1rias op\xe7\xf5es \xe9 a correspond\xeancia girada. A dificuldade escala com o \xe2ngulo de rota\xe7\xe3o, o n\xfamero de distratores e se a rota\xe7\xe3o acontece no plano da imagem ou em profundidade."},hi:{about:"Mental Rotation \u0906\u092a\u0915\u094b \u0926\u094b \u0935\u0938\u094d\u0924\u0941\u090f\u0901 \u0926\u093f\u0916\u093e\u0924\u093e \u0939\u0948 \u2014 \u0906\u092e\u0924\u094c\u0930 \u092a\u0930 \u0918\u0928\u094b\u0902 \u0938\u0947 \u092c\u0928\u0940 \u0906\u0915\u0943\u0924\u093f\u092f\u093e\u0901 \u092f\u093e \u0915\u094b\u0908 \u0938\u092a\u093e\u091f \u0906\u0915\u0943\u0924\u093f \u0914\u0930 \u0909\u0938\u0915\u0947 \u0930\u0942\u092a\u093e\u0902\u0924\u0930 \u2014 \u0914\u0930 \u090f\u0915 \u0939\u0940 \u0938\u0935\u093e\u0932 \u092a\u0942\u091b\u0924\u093e \u0939\u0948: \u0915\u094d\u092f\u093e \u0926\u0942\u0938\u0930\u0940 \u0935\u0939\u0940 \u0935\u0938\u094d\u0924\u0941 \u0939\u0948 \u091c\u094b \u092c\u0938 \u0905\u0902\u0924\u0930\u093f\u0915\u094d\u0937 \u092e\u0947\u0902 \u0918\u0941\u092e\u093e \u0926\u0940 \u0917\u0908 \u0939\u0948, \u092f\u093e \u0935\u0939 \u0909\u0938\u0915\u093e \u0926\u0930\u094d\u092a\u0923-\u092a\u094d\u0930\u0924\u093f\u092c\u093f\u0902\u092c \u0939\u0948? \u0906\u092a \u0909\u0938\u0947 \u0938\u094d\u0915\u094d\u0930\u0940\u0928 \u092a\u0930 \u0928\u0939\u0940\u0902, \u0905\u092a\u0928\u0947 \u0926\u093f\u092e\u093e\u0917 \u092e\u0947\u0902 \u0918\u0941\u092e\u093e\u0924\u0947 \u0939\u0948\u0902 \u0914\u0930 \u091c\u093f\u0924\u0928\u0940 \u0924\u0947\u091c\u093c\u0940 \u0938\u0947 \u0939\u094b \u0938\u0915\u0947 \"\u0938\u092e\u093e\u0928\" \u092f\u093e \"\u0905\u0932\u0917\" \u092a\u0930 \u091f\u0948\u092a \u0915\u0930\u0924\u0947 \u0939\u0948\u0902\u0964",benefit:"\u092f\u0939 \u0938\u094d\u0925\u093e\u0928\u093f\u0915 \u0926\u0943\u0936\u094d\u092f\u0940\u0915\u0930\u0923 \u0915\u094b \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u093f\u0924 \u0915\u0930\u0924\u093e \u0939\u0948 \u2014 \u0915\u093f\u0938\u0940 \u0906\u0915\u0943\u0924\u093f \u0915\u094b \u0926\u093f\u092e\u093e\u0917 \u092e\u0947\u0902 \u0925\u093e\u092e\u0947 \u0930\u0916\u0915\u0930 \u0909\u0938\u0947 \u0930\u0942\u092a\u093e\u0902\u0924\u0930\u093f\u0924 \u0915\u0930\u0928\u0947, \u0918\u0941\u092e\u093e\u0928\u0947 \u0914\u0930 \u0915\u093f\u0938\u0940 \u0926\u0942\u0938\u0930\u0940 \u0906\u0915\u0943\u0924\u093f \u0938\u0947 \u092e\u093f\u0932\u093e\u0928 \u0915\u0930\u0928\u0947 \u0915\u0940 \u0906\u092a\u0915\u0940 \u0915\u094d\u0937\u092e\u0924\u093e\u0964 \u092f\u0939\u0940 \u0935\u0939 \u091a\u0940\u091c\u093c \u0939\u0948 \u091c\u093f\u0938\u0947 \u092e\u0928\u094b\u0935\u0948\u091c\u094d\u091e\u093e\u0928\u093f\u0915 \u092e\u093e\u0928\u0938\u093f\u0915 \u0918\u0941\u092e\u093e\u0935 \u0915\u0939\u0924\u0947 \u0939\u0948\u0902, \u091c\u094b \u0938\u094d\u0925\u093e\u0928\u093f\u0915 \u092c\u0941\u0926\u094d\u0927\u093f \u0915\u0947 \u0938\u092c\u0938\u0947 \u0905\u0927\u093f\u0915 \u0905\u0927\u094d\u092f\u092f\u0928 \u0915\u093f\u090f \u0917\u090f \u0918\u091f\u0915\u094b\u0902 \u092e\u0947\u0902 \u0938\u0947 \u090f\u0915 \u0939\u0948\u0964",history:"\u092f\u0939 \u0915\u093e\u092e \u0938\u0940\u0927\u0947 1971 \u0915\u0947 \u090f\u0915 \u092e\u0936\u0939\u0942\u0930 \u092a\u094d\u0930\u092f\u094b\u0917 \u0938\u0947 \u0928\u093f\u0915\u0932\u093e \u0914\u0930 \u0938\u0902\u091c\u094d\u091e\u093e\u0928\u093e\u0924\u094d\u092e\u0915 \u092e\u0928\u094b\u0935\u093f\u091c\u094d\u091e\u093e\u0928 \u0915\u093e \u090f\u0915 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0914\u091c\u093c\u093e\u0930 \u092c\u0928 \u0917\u092f\u093e\u0964 1978 \u092e\u0947\u0902 Vandenberg \u0914\u0930 Kuse \u0928\u0947 \u092e\u0942\u0932 \u0906\u0915\u0943\u0924\u093f\u092f\u094b\u0902 \u0915\u094b \u0915\u093e\u0917\u091c\u093c-\u0914\u0930-\u092a\u0947\u0902\u0938\u093f\u0932 \u0935\u093e\u0932\u0947 \u0938\u092e\u0942\u0939 \u092a\u0930\u0940\u0915\u094d\u0937\u0923 \u092e\u0947\u0902 \u092c\u0926\u0932 \u0926\u093f\u092f\u093e, \u091c\u093f\u0938\u0928\u0947 \u0907\u0938\u0947 \u0938\u094d\u0915\u0942\u0932\u094b\u0902, \u092a\u094d\u0930\u092f\u094b\u0917\u0936\u093e\u0932\u093e\u0913\u0902 \u0914\u0930 \u0905\u092d\u093f\u0930\u0941\u091a\u093f-\u092a\u0930\u0940\u0915\u094d\u0937\u0923 \u0924\u0915 \u092b\u0948\u0932\u093e \u0926\u093f\u092f\u093e; \u0906\u091c \u092f\u0939 \u0938\u094d\u0925\u093e\u0928\u093f\u0915 \u0915\u094d\u0937\u092e\u0924\u093e \u0914\u0930 \u0932\u0948\u0902\u0917\u093f\u0915 \u092d\u0947\u0926\u094b\u0902 \u092a\u0930 \u0936\u094b\u0927 \u092e\u0947\u0902 \u090f\u0915 \u092e\u093e\u0928\u0915 \u091c\u093e\u0901\u091a \u0939\u0948\u0964",creator:"\u092f\u0939 Roger N. Shepard \u0914\u0930 Jacqueline Metzler \u0915\u0940 \u0926\u0947\u0928 \u0939\u0948, \u091c\u093f\u0928\u0915\u093e \u0936\u094b\u0927-\u092a\u0924\u094d\u0930 \"Mental rotation of three-dimensional objects\" 1971 \u092e\u0947\u0902 Science \u092e\u0947\u0902 \u091b\u092a\u093e\u0964 \u0909\u0928\u094d\u0939\u094b\u0902\u0928\u0947 \u092a\u093e\u092f\u093e \u0915\u093f \u0926\u094b \u0906\u0915\u0943\u0924\u093f\u092f\u093e\u0901 \u092e\u093f\u0932\u0924\u0940 \u0939\u0948\u0902 \u092f\u093e \u0928\u0939\u0940\u0902, \u092f\u0939 \u0924\u092f \u0915\u0930\u0928\u0947 \u092e\u0947\u0902 \u0932\u094b\u0917\u094b\u0902 \u0915\u094b \u091c\u093f\u0924\u0928\u093e \u0938\u092e\u092f \u0932\u0917\u0924\u093e \u0939\u0948 \u0935\u0939 \u0909\u0928\u0915\u0947 \u092c\u0940\u091a \u0915\u0947 \u0915\u094b\u0923 \u0915\u0947 \u0905\u0928\u0941\u092a\u093e\u0924 \u092e\u0947\u0902 \u092c\u0922\u093c\u0924\u093e \u0939\u0948 \u2014 \u092e\u093e\u0928\u094b \u0926\u093f\u092e\u093e\u0917 \u0938\u091a\u092e\u0941\u091a \u0915\u093f\u0938\u0940 \u091b\u0935\u093f \u0915\u094b \u090f\u0915 \u0938\u094d\u0925\u093f\u0930 \u0930\u092b\u093c\u094d\u0924\u093e\u0930 \u0938\u0947 \u0918\u0941\u092e\u093e \u0930\u0939\u093e \u0939\u094b\u0964",methods:"\u0935\u0938\u094d\u0924\u0941 \u092a\u0930 \u0915\u094b\u0908 \u090f\u0915 \u0924\u092f \u0938\u0902\u0926\u0930\u094d\u092d-\u092c\u093f\u0902\u0926\u0941 \u091a\u0941\u0928\u0947\u0902 \u2014 \u0915\u094b\u0908 \u0916\u093c\u093e\u0938 \u092d\u0941\u091c\u093e \u092f\u093e \u0915\u094b\u0928\u093e \u2014 \u0914\u0930 \u092a\u0942\u0930\u0940 \u0906\u0915\u0943\u0924\u093f \u0918\u0941\u092e\u093e\u0924\u0947 \u0935\u0915\u093c\u094d\u0924 \u0928\u091c\u093c\u0930 \u0930\u0916\u0947\u0902 \u0915\u093f \u0935\u0939 \u0915\u0939\u093e\u0901 \u091c\u093e\u0915\u0930 \u092c\u0948\u0920\u0924\u093e \u0939\u0948, \u092c\u091c\u093e\u092f \u0907\u0938\u0915\u0947 \u0915\u093f \u0906\u0915\u0943\u0924\u093f \u0915\u094b \u091f\u0941\u0915\u0921\u093c\u093e-\u0926\u0930-\u091f\u0941\u0915\u0921\u093c\u093e \u0926\u094b\u092c\u093e\u0930\u093e \u092c\u0928\u093e\u090f\u0901\u0964 \u0932\u0915\u094d\u0937\u094d\u092f \u0915\u094b\u0923 \u0924\u0915 \u0938\u092c\u0938\u0947 \u091b\u094b\u091f\u0947 \u0930\u093e\u0938\u094d\u0924\u0947 \u0938\u0947 \u0918\u0941\u092e\u093e\u090f\u0901, \u0914\u0930 \u0936\u0941\u0930\u0941\u0906\u0924 \u092e\u0947\u0902 \u092e\u0942\u0915 \u0915\u0932\u094d\u092a\u0928\u093e \u092a\u0930 \u092d\u0930\u094b\u0938\u093e \u0915\u0930\u0928\u0947 \u0938\u0947 \u092a\u0939\u0932\u0947 \u0926\u093f\u0936\u093e \u091c\u093c\u094b\u0930 \u0938\u0947 \u092c\u094b\u0932\u0947\u0902 (\"\u092a\u0940\u091b\u0947 \u091d\u0941\u0915\u093e\u0913, \u092b\u093f\u0930 \u092c\u093e\u090f\u0901 \u0918\u0941\u092e\u093e\u0913\")\u0964 \u0930\u092b\u093c\u094d\u0924\u093e\u0930 \u0915\u0947 \u0932\u093f\u090f \u0924\u092d\u0940 \u091c\u093c\u094b\u0930 \u0932\u0917\u093e\u090f\u0901 \u091c\u092c \u0906\u092a \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0922\u0902\u0917 \u0938\u0947 \u0938\u091f\u0940\u0915 \u0939\u094b \u091c\u093e\u090f\u0901\u0964",duration:"\u091b\u094b\u091f\u0947, \u092c\u093e\u0930-\u092c\u093e\u0930 \u0915\u0947 \u0938\u0924\u094d\u0930 \u0938\u092c\u0938\u0947 \u0905\u091a\u094d\u091b\u0947 \u0930\u0939\u0924\u0947 \u0939\u0948\u0902: \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u0924\u0940\u0928 \u0938\u0947 \u092a\u093e\u0901\u091a \u092c\u093e\u0930, \u0939\u0930 \u092c\u093e\u0930 10 \u0938\u0947 15 \u092e\u093f\u0928\u091f\u0964 \u092e\u093e\u0928\u0938\u093f\u0915 \u0918\u0941\u092e\u093e\u0935 \u0915\u094b \u0935\u0930\u094d\u0915\u093f\u0902\u0917 \u092e\u0947\u092e\u094b\u0930\u0940 \u092e\u0947\u0902 \u0925\u093e\u092e\u0947 \u0930\u0916\u0928\u093e \u0925\u0915\u093e\u0928\u0947 \u0935\u093e\u0932\u093e \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0925\u0915\u0915\u0930 \u0930\u0917\u0921\u093c\u0924\u0947 \u0930\u0939\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u091c\u092c \u0938\u091f\u0940\u0915\u0924\u093e \u0917\u093f\u0930\u0928\u0947 \u0932\u0917\u0947 \u0924\u094b \u0930\u0941\u0915 \u091c\u093e\u090f\u0901\u0964",research:"\u092a\u094d\u0930\u092e\u093e\u0923 \u0938\u092c\u0938\u0947 \u0920\u094b\u0938 \u0920\u0940\u0915 \u0909\u0938\u0940 \u092c\u093e\u0924 \u0915\u0947 \u0932\u093f\u090f \u0939\u0948\u0902 \u091c\u093f\u0938\u0915\u0940 \u0906\u092a \u0909\u092e\u094d\u092e\u0940\u0926 \u0915\u0930\u0947\u0902\u0917\u0947 \u2014 \u0906\u092a \u0916\u093c\u0941\u0926 \u092e\u093e\u0928\u0938\u093f\u0915 \u0918\u0941\u092e\u093e\u0935 \u092e\u0947\u0902 \u0924\u0947\u091c\u093c \u0914\u0930 \u0938\u091f\u0940\u0915 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 217 \u0905\u0927\u094d\u092f\u092f\u0928\u094b\u0902 \u0915\u0947 \u090f\u0915 \u092c\u0921\u093c\u0947 2013 \u0915\u0947 \u092e\u0947\u091f\u093e-\u0935\u093f\u0936\u094d\u0932\u0947\u0937\u0923 (Uttal \u0914\u0930 \u0938\u093e\u0925\u0940) \u0928\u0947 \u092a\u093e\u092f\u093e \u0915\u093f \u0938\u094d\u0925\u093e\u0928\u093f\u0915 \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0922\u0902\u0917 \u0938\u0947 \u0938\u094d\u0925\u093e\u0928\u093f\u0915 \u092a\u0930\u0940\u0915\u094d\u0937\u0923-\u0905\u0902\u0915 \u0938\u0941\u0927\u093e\u0930\u0924\u093e \u0939\u0948, \u0914\u0930 \u0907\u0938\u0915\u0947 \u0905\u0938\u0930 \u091f\u093f\u0915 \u0938\u0915\u0924\u0947 \u0939\u0948\u0902 \u0914\u0930 \u092e\u093f\u0932\u0924\u0947-\u091c\u0941\u0932\u0924\u0947 \u0915\u093e\u092e\u094b\u0902 \u0924\u0915 \u092a\u0939\u0941\u0901\u091a \u0938\u0915\u0924\u0947 \u0939\u0948\u0902\u0964 \u0915\u0941\u091b \u0905\u0927\u094d\u092f\u092f\u0928\u094b\u0902, \u091c\u0948\u0938\u0947 Feng, Spence \u0914\u0930 Pratt (2007), \u0928\u0947 \u0924\u094b \u092f\u0939 \u0924\u0915 \u092a\u093e\u092f\u093e \u0915\u093f \u090f\u0915\u094d\u0936\u0928 \u0935\u0940\u0921\u093f\u092f\u094b \u0917\u0947\u092e \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u0932\u0948\u0902\u0917\u093f\u0915 \u0905\u0902\u0924\u0930 \u0915\u094b \u0915\u092e \u0915\u0930 \u0926\u0947\u0924\u0947 \u0939\u0948\u0902\u0964 \u092a\u0930 \u092c\u0921\u093c\u0947 \u0926\u093e\u0935\u0947 \u2014 \u0915\u093f \u0907\u0938\u0938\u0947 \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u092c\u0941\u0926\u094d\u0927\u093f \u092c\u0922\u093c\u0924\u0940 \u0939\u0948 \u092f\u093e \u0917\u0923\u093f\u0924 \u0914\u0930 STEM \u0909\u092a\u0932\u092c\u094d\u0927\u093f \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0922\u0902\u0917 \u0938\u0947 \u092c\u0922\u093c\u0924\u0940 \u0939\u0948 \u2014 \u0915\u092e\u091c\u093c\u094b\u0930 \u0914\u0930 \u0935\u093f\u0935\u093e\u0926\u093f\u0924 \u0939\u0948\u0902, \u0907\u0938\u0932\u093f\u090f \u0926\u0942\u0930 \u0915\u0947 \u0939\u0938\u094d\u0924\u093e\u0902\u0924\u0930\u0923 \u0915\u094b \u090f\u0915 \u0938\u0902\u092d\u093e\u0935\u0928\u093e \u092e\u093e\u0928\u0947\u0902, \u0935\u093e\u0926\u093e \u0928\u0939\u0940\u0902\u0964",rec:"\u0930\u092b\u093c\u094d\u0924\u093e\u0930 \u0927\u0940\u092e\u0940 \u0915\u0930\u0947\u0902 \u0914\u0930 \u092a\u0939\u0932\u0947 \u0938\u091f\u0940\u0915\u0924\u093e \u092a\u0930 \u0927\u094d\u092f\u093e\u0928 \u0926\u0947\u0902; \u0905\u0917\u0930 \u0906\u092a \u092a\u0942\u0930\u0947 \u092d\u0930\u094b\u0938\u0947 \u0938\u0947 \u0926\u0930\u094d\u092a\u0923-\u092a\u094d\u0930\u0924\u093f\u092c\u093f\u0902\u092c\u094b\u0902 \u0915\u094b \"\u0938\u092e\u093e\u0928\" \u092c\u0924\u093e \u0930\u0939\u0947 \u0939\u0948\u0902 \u0924\u094b \u0930\u092b\u093c\u094d\u0924\u093e\u0930 \u092c\u0947\u0915\u093e\u0930 \u0939\u0948\u0964",faq:[["\u092c\u0921\u093c\u0947 \u0918\u0941\u092e\u093e\u0935 \u0907\u0924\u0928\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0927\u0940\u092e\u0947 \u0915\u094d\u092f\u094b\u0902 \u0932\u0917\u0924\u0947 \u0939\u0948\u0902?","\u0915\u094d\u092f\u094b\u0902\u0915\u093f \u0906\u092a \u0905\u0938\u0932 \u092e\u0947\u0902 \u0935\u0938\u094d\u0924\u0941 \u0915\u094b \u0905\u092a\u0928\u0947 \u0926\u093f\u092e\u093e\u0917 \u092e\u0947\u0902 \u0915\u0930\u0940\u092c-\u0915\u0930\u0940\u092c \u090f\u0915 \u0938\u094d\u0925\u093f\u0930 \u0930\u092b\u093c\u094d\u0924\u093e\u0930 \u0938\u0947 \u0918\u0941\u092e\u093e \u0930\u0939\u0947 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902, \u0907\u0938\u0932\u093f\u090f \u092c\u0921\u093c\u0947 \u0915\u094b\u0923 \u092e\u0947\u0902 \u092c\u0938 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u092e\u093e\u0928\u0938\u093f\u0915 \u0938\u092b\u093c\u0930 \u0932\u0917\u0924\u093e \u0939\u0948\u0964 Shepard \u0914\u0930 Metzler \u0928\u0947 \u0920\u0940\u0915 \u092f\u0939\u0940 \u092e\u093e\u092a\u093e \u2014 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0938\u092e\u092f \u0915\u094b\u0923 \u0915\u0947 \u0938\u093e\u0925 \u0932\u0917\u092d\u0917 \u0930\u0948\u0916\u093f\u0915 \u0930\u0942\u092a \u0938\u0947 \u091a\u0922\u093c\u0924\u093e \u0939\u0948\u0964"],["\u092e\u0948\u0902 \u0926\u0930\u094d\u092a\u0923-\u092a\u094d\u0930\u0924\u093f\u092c\u093f\u0902\u092c\u094b\u0902 \u0915\u094b \u092c\u093e\u0930-\u092c\u093e\u0930 \u092e\u0947\u0932 \u0938\u092e\u091d \u092c\u0948\u0920\u0924\u093e \u0939\u0942\u0901\u0964 \u0915\u094d\u092f\u093e \u092f\u0939 \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u0939\u0948?","\u0939\u093e\u0901, \u0926\u0930\u094d\u092a\u0923\u093f\u0924 \u091c\u094b\u0921\u093c\u0947 \u0935\u0939\u0940 \u092e\u0936\u0939\u0942\u0930 \u091c\u093e\u0932 \u0939\u0948\u0902 \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u091c\u092c \u0924\u0915 \u0906\u092a \u0909\u0928\u0915\u0940 \u0926\u093f\u0936\u093e-\u0939\u0938\u094d\u0924\u0924\u093e \u0928 \u091c\u093e\u0901\u091a\u0947\u0902 \u0935\u0947 \u090f\u0915 \u091c\u0948\u0938\u0947 \u0926\u093f\u0916\u0924\u0947 \u0939\u0948\u0902\u0964 \u0915\u093f\u0938\u0940 \u090f\u0915 \u0905\u0938\u092e\u092e\u093f\u0924 \u0935\u093f\u0936\u0947\u0937\u0924\u093e \u092a\u0930 \u091f\u093f\u0915\u0947\u0902 \u0914\u0930 \u092a\u0942\u091b\u0947\u0902 \u0915\u093f \u0935\u0939 \u0938\u0939\u0940 \u0913\u0930 \u091c\u093e\u0915\u0930 \u092c\u0948\u0920\u0924\u0940 \u0939\u0948 \u092f\u093e \u0928\u0939\u0940\u0902 \u2014 \u092f\u0939\u0940 \u0905\u0938\u0932\u0940 \u0918\u0941\u092e\u093e\u0935 \u0915\u094b \u092a\u0930\u093e\u0935\u0930\u094d\u0924\u0928 \u0938\u0947 \u0905\u0932\u0917 \u0915\u0930\u0924\u093e \u0939\u0948\u0964"],["\u0915\u094d\u092f\u093e \u0907\u0938\u0938\u0947 \u092e\u0948\u0902 \u0928\u0915\u094d\u0936\u0947 \u092a\u0922\u093c\u0928\u0947 \u092f\u093e \u0917\u093e\u0921\u093c\u0940 \u092a\u093e\u0930\u094d\u0915 \u0915\u0930\u0928\u0947 \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u092c\u0928 \u091c\u093e\u090a\u0901\u0917\u093e?","\u092f\u0939 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0922\u0902\u0917 \u0938\u0947 \u0906\u092a\u0915\u094b \u092e\u093e\u0928\u0938\u093f\u0915 \u0918\u0941\u092e\u093e\u0935 \u0914\u0930 \u092e\u093f\u0932\u0924\u0947-\u091c\u0941\u0932\u0924\u0947 \u0938\u094d\u0925\u093e\u0928\u093f\u0915 \u092a\u0930\u0940\u0915\u094d\u0937\u0923\u094b\u0902 \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u092c\u0928\u093e\u090f\u0917\u093e; \u092f\u0939 \u0926\u093f\u0936\u093e-\u0916\u094b\u091c \u092f\u093e \u092a\u093e\u0930\u094d\u0915\u093f\u0902\u0917 \u091c\u0948\u0938\u0947 \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0947 \u0915\u093e\u092e\u094b\u0902 \u0924\u0915 \u092a\u0939\u0941\u0901\u091a\u0924\u093e \u0939\u0948 \u092f\u093e \u0928\u0939\u0940\u0902, \u092f\u0939 \u0938\u0902\u092d\u0935 \u0924\u094b \u0939\u0948 \u092a\u0930 \u0905\u091a\u094d\u091b\u0940 \u0924\u0930\u0939 \u0938\u093f\u0926\u094d\u0927 \u0928\u0939\u0940\u0902\u0964 \u0905\u0938\u0932\u0940-\u0926\u0941\u0928\u093f\u092f\u093e \u0915\u0947 \u092b\u093c\u093e\u092f\u0926\u094b\u0902 \u0915\u094b \u090f\u0915 \u092c\u094b\u0928\u0938 \u092e\u093e\u0928\u0947\u0902, \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0940 \u0935\u091c\u0939 \u0928\u0939\u0940\u0902\u0964"]],variants:"\u0930\u0942\u092a \u0938\u092a\u093e\u091f 2D \u0905\u0915\u094d\u0937\u0930\u094b\u0902 \u092f\u093e \u0906\u0915\u0943\u0924\u093f\u092f\u094b\u0902 (\u0906\u0938\u093e\u0928) \u0938\u0947 \u0932\u0947\u0915\u0930 \u092e\u0942\u0932 \u091c\u0948\u0938\u0940 3D \u0918\u0928 \u0906\u0915\u0943\u0924\u093f\u092f\u094b\u0902 (\u0915\u0920\u093f\u0928) \u0924\u0915 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \"\u0938\u092e\u093e\u0928 \u092f\u093e \u0926\u0930\u094d\u092a\u0923\u093f\u0924?\" \u0935\u093e\u0932\u0947 \u0928\u093f\u0930\u094d\u0923\u092f\u094b\u0902 \u0938\u0947 \u0932\u0947\u0915\u0930 \u0915\u0908 \u0935\u093f\u0915\u0932\u094d\u092a\u094b\u0902 \u092e\u0947\u0902 \u0938\u0947 \u0918\u0941\u092e\u093e\u092f\u093e \u0939\u0941\u0906 \u092e\u0947\u0932 \u091a\u0941\u0928\u0928\u0947 \u0924\u0915\u0964 \u0915\u0920\u093f\u0928\u093e\u0908 \u0918\u0941\u092e\u093e\u0935 \u0915\u0947 \u0915\u094b\u0923, \u0927\u094d\u092f\u093e\u0928 \u092d\u091f\u0915\u093e\u0928\u0947 \u0935\u093e\u0932\u094b\u0902 \u0915\u0940 \u0938\u0902\u0916\u094d\u092f\u093e, \u0914\u0930 \u0907\u0938 \u092c\u093e\u0924 \u0915\u0947 \u0938\u093e\u0925 \u092c\u0922\u093c\u0924\u0940 \u0939\u0948 \u0915\u093f \u0918\u0941\u092e\u093e\u0935 \u091a\u093f\u0924\u094d\u0930-\u0924\u0932 \u092e\u0947\u0902 \u0939\u094b\u0924\u093e \u0939\u0948 \u092f\u093e \u0917\u0939\u0930\u093e\u0908 \u092e\u0947\u0902\u0964"},zh:{about:"\u300c\u5fc3\u7406\u65cb\u8f6c\u300d\u4f1a\u7ed9\u4f60\u5448\u73b0\u4e24\u4e2a\u7269\u4f53\u2014\u2014\u901a\u5e38\u662f\u7531\u65b9\u5757\u642d\u6210\u7684\u7acb\u4f53\u5f62\u72b6\uff0c\u6216\u662f\u4e00\u4e2a\u5e73\u9762\u56fe\u5f62\u53ca\u5176\u53d8\u4f53\u2014\u2014\u5e76\u63d0\u51fa\u4e00\u4e2a\u95ee\u9898\uff1a\u7b2c\u4e8c\u4e2a\u7a76\u7adf\u662f\u540c\u4e00\u4e2a\u7269\u4f53\u5728\u7a7a\u95f4\u4e2d\u5355\u7eaf\u8f6c\u4e86\u4e2a\u65b9\u5411\uff0c\u8fd8\u662f\u5b83\u7684\u955c\u50cf\uff1f\u4f60\u8981\u5728\u8111\u4e2d\uff08\u800c\u4e0d\u662f\u5728\u5c4f\u5e55\u4e0a\uff09\u628a\u5b83\u8f6c\u8d77\u6765\uff0c\u7136\u540e\u5c3d\u53ef\u80fd\u5feb\u5730\u70b9\u9009\u300c\u76f8\u540c\u300d\u6216\u300c\u4e0d\u540c\u300d\u3002",benefit:"\u5b83\u8bad\u7ec3\u7a7a\u95f4\u60f3\u8c61\u529b\u2014\u2014\u4e5f\u5c31\u662f\u4f60\u5728\u8111\u4e2d\u4fdd\u6301\u4e00\u4e2a\u5f62\u72b6\u5e76\u5bf9\u5b83\u8fdb\u884c\u53d8\u6362\u3001\u628a\u5b83\u65cb\u8f6c\u540e\u4e0e\u53e6\u4e00\u4e2a\u5f62\u72b6\u4f5c\u6bd4\u5bf9\u7684\u80fd\u529b\u3002\u8fd9\u6b63\u662f\u5fc3\u7406\u5b66\u5bb6\u6240\u8bf4\u7684\u300c\u5fc3\u7406\u65cb\u8f6c\u300d\u7684\u6838\u5fc3\uff0c\u4e5f\u662f\u7a7a\u95f4\u667a\u529b\u4e2d\u88ab\u7814\u7a76\u5f97\u6700\u591a\u7684\u6210\u5206\u4e4b\u4e00\u3002",history:"\u8fd9\u9879\u4efb\u52a1\u76f4\u63a5\u8131\u80ce\u4e8e1971\u5e74\u4e00\u4e2a\u8457\u540d\u7684\u5355\u9879\u5b9e\u9a8c\uff0c\u540e\u6765\u6210\u4e86\u8ba4\u77e5\u5fc3\u7406\u5b66\u7684\u4e3b\u529b\u5de5\u5177\u30021978\u5e74\uff0c\u8303\u767b\u4f2f\u683c\uff08Vandenberg\uff09\u548c\u5e93\u585e\uff08Kuse\uff09\u628a\u6700\u521d\u7684\u56fe\u5f62\u6539\u9020\u6210\u4e86\u4e00\u5957\u7eb8\u7b14\u56e2\u4f53\u6d4b\u9a8c\uff0c\u4f7f\u5b83\u4f20\u64ad\u8fdb\u4e86\u5b66\u6821\u3001\u5b9e\u9a8c\u5ba4\u548c\u80fd\u529b\u503e\u5411\u6d4b\u8bd5\u4e2d\uff1b\u5982\u4eca\uff0c\u5b83\u662f\u5173\u4e8e\u7a7a\u95f4\u80fd\u529b\u4ee5\u53ca\u4e24\u6027\u5dee\u5f02\u7814\u7a76\u4e2d\u7684\u4e00\u9879\u6807\u51c6\u6d4b\u91cf\u624b\u6bb5\u3002",creator:"\u5b83\u51fa\u81ea\u7f57\u6770\xb7N\xb7\u8c22\u6cfc\u5fb7\uff08Roger N. Shepard\uff09\u548c\u6770\u594e\u7433\xb7\u6885\u8328\u52d2\uff08Jacqueline Metzler\uff09\uff0c\u4ed6\u4eec\u7684\u8bba\u6587\u300a\u4e09\u7ef4\u7269\u4f53\u7684\u5fc3\u7406\u65cb\u8f6c\u300b\uff08Mental rotation of three-dimensional objects\uff09\u4e8e1971\u5e74\u53d1\u8868\u5728\u300a\u79d1\u5b66\u300b\uff08Science\uff09\u6742\u5fd7\u4e0a\u3002\u4ed6\u4eec\u53d1\u73b0\uff0c\u4eba\u4eec\u5224\u65ad\u4e24\u4e2a\u5f62\u72b6\u662f\u5426\u4e00\u81f4\u6240\u9700\u7684\u65f6\u95f4\uff0c\u4f1a\u968f\u7740\u4e24\u8005\u4e4b\u95f4\u5939\u89d2\u7684\u589e\u5927\u800c\u6210\u6bd4\u4f8b\u5730\u589e\u52a0\u2014\u2014\u4eff\u4f5b\u5fc3\u667a\u771f\u7684\u5728\u4ee5\u4e00\u4e2a\u7a33\u5b9a\u7684\u901f\u5ea6\u65cb\u8f6c\u4e00\u5e45\u56fe\u50cf\u3002",methods:"\u5728\u7269\u4f53\u4e0a\u9009\u5b9a\u4e00\u4e2a\u56fa\u5b9a\u7684\u53c2\u7167\u70b9\u2014\u2014\u67d0\u6761\u6709\u7279\u70b9\u7684\u300c\u80f3\u818a\u300d\u6216\u67d0\u4e2a\u89d2\u2014\u2014\u5728\u4f60\u8f6c\u52a8\u6574\u4e2a\u5f62\u72b6\u65f6\u8ffd\u8e2a\u5b83\u843d\u5230\u54ea\u91cc\uff0c\u800c\u4e0d\u662f\u4e00\u5757\u4e00\u5757\u5730\u628a\u5b83\u91cd\u753b\u4e00\u904d\u3002\u6cbf\u7740\u901a\u5f80\u76ee\u6807\u89d2\u5ea6\u7684\u6700\u77ed\u8def\u5f84\u6765\u65cb\u8f6c\uff1b\u4e00\u5f00\u59cb\u5148\u628a\u65b9\u5411\u5927\u58f0\u8bf4\u51fa\u6765\uff08\u300c\u5f80\u540e\u5012\uff0c\u518d\u5411\u5de6\u8f6c\u300d\uff09\uff0c\u7b49\u719f\u7ec3\u4e86\u518d\u53bb\u4fe1\u4efb\u65e0\u58f0\u7684\u8111\u4e2d\u60f3\u8c61\u3002\u53ea\u6709\u5f53\u4f60\u80fd\u7a33\u5b9a\u505a\u5230\u51c6\u786e\u4e4b\u540e\uff0c\u518d\u53bb\u8ffd\u6c42\u901f\u5ea6\u3002",duration:"\u77ed\u800c\u9891\u7e41\u7684\u7ec3\u4e60\u6548\u679c\u6700\u597d\uff1a\u6bcf\u6b2110\u523015\u5206\u949f\uff0c\u6bcf\u5468\u4e09\u5230\u4e94\u6b21\u3002\u5fc3\u7406\u65cb\u8f6c\u8981\u9760\u5de5\u4f5c\u8bb0\u5fc6\u7ef4\u6301\uff0c\u5f88\u8017\u795e\uff0c\u6240\u4ee5\u5f53\u51c6\u786e\u7387\u5f00\u59cb\u4e0b\u6ed1\u65f6\u5c31\u505c\u4e0b\u6765\uff0c\u800c\u4e0d\u8981\u5e26\u7740\u75b2\u52b3\u786c\u6491\u3002",research:"\u8bc1\u636e\u6700\u624e\u5b9e\u7684\uff0c\u6070\u6070\u662f\u4f60\u80fd\u9884\u6599\u5230\u7684\u90a3\u4e00\u70b9\u2014\u2014\u4f60\u4f1a\u66f4\u5feb\u3001\u66f4\u51c6\u5730\u5b8c\u6210\u5fc3\u7406\u65cb\u8f6c\u672c\u8eab\uff1b\u800c2013\u5e74\u4e00\u9879\u7eb3\u5165217\u9879\u7814\u7a76\u7684\u5927\u578b\u5143\u5206\u6790\uff08Uttal \u53ca\u5176\u540c\u4e8b\uff09\u53d1\u73b0\uff0c\u7a7a\u95f4\u8bad\u7ec3\u80fd\u53ef\u9760\u5730\u63d0\u9ad8\u7a7a\u95f4\u6d4b\u9a8c\u5f97\u5206\uff0c\u5176\u6548\u679c\u53ef\u4ee5\u6301\u7eed\uff0c\u5e76\u8fc1\u79fb\u5230\u7c7b\u4f3c\u7684\u4efb\u52a1\u4e0a\u3002\u4e00\u4e9b\u7814\u7a76\uff0c\u6bd4\u5982 Feng\u3001Spence \u548c Pratt\uff082007\uff09\uff0c\u751a\u81f3\u53d1\u73b0\u52a8\u4f5c\u7c7b\u7535\u5b50\u6e38\u620f\u7f29\u5c0f\u4e86\u60ef\u5e38\u7684\u4e24\u6027\u5dee\u8ddd\u3002\u4f46\u90a3\u4e9b\u66f4\u5927\u7684\u8bf4\u6cd5\u2014\u2014\u5373\u5b83\u80fd\u63d0\u5347\u4e00\u822c\u667a\u529b\uff0c\u6216\u80fd\u53ef\u9760\u5730\u63d0\u9ad8\u6570\u5b66\u548c STEM \u6210\u7ee9\u2014\u2014\u5219\u8981\u8584\u5f31\u5f97\u591a\uff0c\u4e5f\u5b58\u5728\u4e89\u8bae\uff0c\u6240\u4ee5\u8bf7\u628a\u8fdc\u8fc1\u79fb\u5f53\u4f5c\u4e00\u79cd\u53ef\u80fd\uff0c\u800c\u975e\u4e00\u9879\u627f\u8bfa\u3002",rec:"\u653e\u6162\u901f\u5ea6\uff0c\u9996\u5148\u4ee5\u51c6\u786e\u4e3a\u76ee\u6807\uff1b\u5982\u679c\u4f60\u81ea\u4fe1\u6ee1\u6ee1\u5730\u628a\u955c\u50cf\u5224\u6210\u300c\u76f8\u540c\u300d\uff0c\u90a3\u901f\u5ea6\u6beb\u65e0\u4ef7\u503c\u3002",faq:[["\u4e3a\u4ec0\u4e48\u65cb\u8f6c\u89d2\u5ea6\u8d8a\u5927\uff0c\u611f\u89c9\u5c31\u6162\u90a3\u4e48\u591a\uff1f","\u56e0\u4e3a\u4f60\u5b9e\u9645\u4e0a\u662f\u5728\u8111\u4e2d\u4ee5\u4e00\u4e2a\u5927\u81f4\u6052\u5b9a\u7684\u901f\u7387\u65cb\u8f6c\u90a3\u4e2a\u7269\u4f53\uff0c\u6240\u4ee5\u66f4\u5927\u7684\u5939\u89d2\u4e0d\u8fc7\u662f\u9700\u8981\u66f4\u591a\u7684\u300c\u5fc3\u7406\u8def\u7a0b\u300d\u3002\u8c22\u6cfc\u5fb7\u548c\u6885\u8328\u52d2\u6d4b\u91cf\u7684\u6b63\u662f\u8fd9\u4e00\u70b9\u2014\u2014\u53cd\u5e94\u65f6\u95f4\u51e0\u4e4e\u968f\u89d2\u5ea6\u7ebf\u6027\u4e0a\u5347\u3002"],["\u6211\u8001\u662f\u628a\u955c\u50cf\u5f53\u6210\u5339\u914d\uff0c\u8fd9\u6b63\u5e38\u5417\uff1f","\u6b63\u5e38\uff0c\u955c\u50cf\u7684\u724c\u5bf9\u662f\u7ecf\u5178\u7684\u9677\u9631\uff0c\u56e0\u4e3a\u5b83\u4eec\u770b\u4e0a\u53bb\u4e00\u6a21\u4e00\u6837\uff0c\u76f4\u5230\u4f60\u53bb\u68c0\u67e5\u300c\u624b\u6027\u300d\uff08\u5de6\u53f3\u671d\u5411\uff09\u4e3a\u6b62\u3002\u9501\u5b9a\u67d0\u4e00\u4e2a\u4e0d\u5bf9\u79f0\u7684\u7279\u5f81\uff0c\u95ee\u95ee\u5b83\u6700\u7ec8\u662f\u4e0d\u662f\u843d\u5728\u4e86\u6b63\u786e\u7684\u4e00\u4fa7\u2014\u2014\u8fd9\u80fd\u628a\u771f\u6b63\u7684\u65cb\u8f6c\u548c\u955c\u50cf\u53cd\u5c04\u533a\u5206\u5f00\u6765\u3002"],["\u8fd9\u4f1a\u8ba9\u6211\u66f4\u64c5\u957f\u770b\u5730\u56fe\u6216\u505c\u8f66\u5417\uff1f","\u5b83\u4f1a\u53ef\u9760\u5730\u8ba9\u4f60\u66f4\u64c5\u957f\u5fc3\u7406\u65cb\u8f6c\u548c\u7c7b\u4f3c\u7684\u7a7a\u95f4\u6d4b\u9a8c\uff1b\u81f3\u4e8e\u8fd9\u80fd\u5426\u8fc1\u79fb\u5230\u5bfc\u822a\u6216\u505c\u8f66\u8fd9\u7c7b\u65e5\u5e38\u4efb\u52a1\u4e0a\uff0c\u5219\u8bf4\u5f97\u901a\u4f46\u5c1a\u672a\u5f97\u5230\u5145\u5206\u8bc1\u5b9e\u3002\u8bf7\u628a\u73b0\u5b9e\u4e16\u754c\u4e2d\u7684\u6536\u76ca\u5f53\u4f5c\u4e00\u4efd\u989d\u5916\u7684\u8d60\u793c\uff0c\u800c\u4e0d\u662f\u4f60\u8bad\u7ec3\u7684\u7406\u7531\u3002"]],variants:"\u7248\u672c\u4ece\u5e73\u9762\u76842D\u5b57\u6bcd\u6216\u56fe\u5f62\uff08\u8f83\u6613\uff09\uff0c\u5230\u50cf\u6700\u521d\u5b9e\u9a8c\u90a3\u6837\u76843D\u65b9\u5757\u7acb\u4f53\uff08\u8f83\u96be\uff09\uff1b\u4ece\u300c\u76f8\u540c\u8fd8\u662f\u955c\u50cf\uff1f\u300d\u7684\u5224\u65ad\uff0c\u5230\u4ece\u82e5\u5e72\u9009\u9879\u4e2d\u6311\u51fa\u54ea\u4e00\u4e2a\u624d\u662f\u65cb\u8f6c\u540e\u7684\u5339\u914d\u9879\uff0c\u5e94\u6709\u5c3d\u6709\u3002\u96be\u5ea6\u4f1a\u968f\u65cb\u8f6c\u89d2\u5ea6\u3001\u5e72\u6270\u9879\u7684\u6570\u91cf\uff0c\u4ee5\u53ca\u65cb\u8f6c\u7a76\u7adf\u53d1\u751f\u5728\u753b\u9762\u5e73\u9762\u5185\u8fd8\u662f\u5728\u7eb5\u6df1\u65b9\u5411\u4e0a\u800c\u53d8\u5316\u3002"}},mnemonics:{ru:{about:"\xab\u041c\u043d\u0435\u043c\u043e\u043d\u0438\u043a\u0430: \u043f\u043e\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c\xbb \u043f\u043e\u043a\u0430\u0437\u044b\u0432\u0430\u0435\u0442 \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u0439 \u0443\u043f\u043e\u0440\u044f\u0434\u043e\u0447\u0435\u043d\u043d\u044b\u0439 \u0441\u043f\u0438\u0441\u043e\u043a \u0438 \u043f\u0440\u043e\u0441\u0438\u0442 \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u0435\u0441\u0442\u0438 \u0435\u0433\u043e \u0432 \u0442\u043e\u043c \u0436\u0435 \u043f\u043e\u0440\u044f\u0434\u043a\u0435. \u0421\u043c\u044b\u0441\u043b \u043d\u0435 \u0432 \u0442\u043e\u043c, \u0447\u0442\u043e\u0431\u044b \u043f\u044f\u043b\u0438\u0442\u044c\u0441\u044f \u0438 \u0437\u0443\u0431\u0440\u0438\u0442\u044c, \u0430 \u0432 \u0442\u043e\u043c, \u0447\u0442\u043e\u0431\u044b \u0441\u0432\u044f\u0437\u0430\u0442\u044c \u043a\u0430\u0436\u0434\u044b\u0439 \u044d\u043b\u0435\u043c\u0435\u043d\u0442 \u0441\u043e \u0441\u043b\u0435\u0434\u0443\u044e\u0449\u0438\u043c \u044f\u0440\u043a\u0438\u043c \u043e\u0431\u0440\u0430\u0437\u043e\u043c \u0438\u043b\u0438 \u043c\u044b\u0441\u043b\u0435\u043d\u043d\u044b\u043c \u043c\u0430\u0440\u0448\u0440\u0443\u0442\u043e\u043c \u043f\u043e \u0437\u043d\u0430\u043a\u043e\u043c\u043e\u043c\u0443 \u043c\u0435\u0441\u0442\u0443 \u2014 \u0442\u043e\u0433\u0434\u0430 \u043f\u043e\u0440\u044f\u0434\u043e\u043a \u0434\u0435\u0440\u0436\u0438\u0442\u0441\u044f \u043d\u0430 \u0430\u0441\u0441\u043e\u0446\u0438\u0430\u0446\u0438\u044f\u0445, \u0430 \u043d\u0435 \u043d\u0430 \u0443\u0441\u0438\u043b\u0438\u0438.",benefit:"\u0422\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u043e\u0441\u043e\u0437\u043d\u0430\u043d\u043d\u043e\u0435 \u0430\u0441\u0441\u043e\u0446\u0438\u0430\u0442\u0438\u0432\u043d\u043e\u0435 \u0437\u0430\u043f\u043e\u043c\u0438\u043d\u0430\u043d\u0438\u0435 \u0438 \u0443\u043f\u043e\u0440\u044f\u0434\u043e\u0447\u0435\u043d\u043d\u043e\u0435 \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u0435\u0434\u0435\u043d\u0438\u0435: \u0443\u043c\u0435\u043d\u0438\u0435 \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0442\u044c \u043f\u043e\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c, \u043f\u0440\u0438\u0434\u0430\u0432\u0430\u0442\u044c \u0441\u043c\u044b\u0441\u043b \u0441\u043b\u0443\u0447\u0430\u0439\u043d\u044b\u043c \u043d\u0430 \u0432\u0438\u0434 \u044d\u043b\u0435\u043c\u0435\u043d\u0442\u0430\u043c \u0438 \u0432\u044b\u0434\u0430\u0432\u0430\u0442\u044c \u0438\u0445 \u0432 \u043f\u0440\u0430\u0432\u0438\u043b\u044c\u043d\u043e\u043c \u043f\u043e\u0440\u044f\u0434\u043a\u0435. \u0421\u043e \u0432\u0440\u0435\u043c\u0435\u043d\u0435\u043c \u0437\u0430\u043a\u0440\u0435\u043f\u043b\u044f\u0435\u0442\u0441\u044f \u043f\u0440\u0438\u0432\u044b\u0447\u043a\u0430 \u043f\u0435\u0440\u0435\u0432\u043e\u0434\u0438\u0442\u044c \u0430\u0431\u0441\u0442\u0440\u0430\u043a\u0442\u043d\u044b\u0439 \u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b \u0432 \u043a\u043e\u043d\u043a\u0440\u0435\u0442\u043d\u044b\u0435 \u043e\u0431\u0440\u0430\u0437\u044b.",history:"\u0412 \u043e\u0441\u043d\u043e\u0432\u0435 \u2014 \u043e\u0434\u0438\u043d \u0438\u0437 \u0441\u0442\u0430\u0440\u0435\u0439\u0448\u0438\u0445 \u0437\u0430\u0434\u043e\u043a\u0443\u043c\u0435\u043d\u0442\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u044b\u0445 \u043f\u0440\u0438\u0451\u043c\u043e\u0432 \u043f\u0430\u043c\u044f\u0442\u0438 \u0437\u0430\u043f\u0430\u0434\u043d\u043e\u0439 \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u0438, \u0442\u0430\u043a \u043d\u0430\u0437\u044b\u0432\u0430\u0435\u043c\u043e\u0435 \xab\u0438\u0441\u043a\u0443\u0441\u0441\u0442\u0432\u043e \u043f\u0430\u043c\u044f\u0442\u0438\xbb. \u0418\u043c \u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u043b\u0438\u0441\u044c \u0433\u0440\u0435\u0447\u0435\u0441\u043a\u0438\u0435 \u0438 \u0440\u0438\u043c\u0441\u043a\u0438\u0435 \u043e\u0440\u0430\u0442\u043e\u0440\u044b, \u0447\u0442\u043e\u0431\u044b \u0434\u0435\u0440\u0436\u0430\u0442\u044c \u0432 \u0433\u043e\u043b\u043e\u0432\u0435 \u0434\u043b\u0438\u043d\u043d\u044b\u0435 \u0440\u0435\u0447\u0438; \u043e\u043d \u043f\u0440\u043e\u0448\u0451\u043b \u0447\u0435\u0440\u0435\u0437 \u0442\u0440\u0430\u043a\u0442\u0430\u0442\u044b \u0421\u0440\u0435\u0434\u043d\u0435\u0432\u0435\u043a\u043e\u0432\u044c\u044f \u0438 \u0412\u043e\u0437\u0440\u043e\u0436\u0434\u0435\u043d\u0438\u044f \u0438 \u0434\u043e\u0436\u0438\u043b \u0434\u043e \u043d\u0430\u0448\u0438\u0445 \u0434\u043d\u0435\u0439 \u0432 \u0441\u043f\u043e\u0440\u0442\u0438\u0432\u043d\u043e\u0439 \u043f\u0430\u043c\u044f\u0442\u0438, \u0433\u0434\u0435 \u0430\u0442\u043b\u0435\u0442\u044b \u0442\u0430\u043a \u0437\u0430\u043f\u043e\u043c\u0438\u043d\u0430\u044e\u0442 \u043a\u043e\u043b\u043e\u0434\u044b \u043a\u0430\u0440\u0442 \u0438 \u0434\u043b\u0438\u043d\u043d\u044b\u0435 \u0440\u044f\u0434\u044b \u0446\u0438\u0444\u0440.",creator:"\u0415\u0434\u0438\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0433\u043e \u0438\u0437\u043e\u0431\u0440\u0435\u0442\u0430\u0442\u0435\u043b\u044f \u043d\u0435\u0442. \u041f\u0440\u0438\u0451\u043c \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u043e\u043d\u043d\u043e \u043f\u0440\u0438\u043f\u0438\u0441\u044b\u0432\u0430\u044e\u0442 \u0433\u0440\u0435\u0447\u0435\u0441\u043a\u043e\u043c\u0443 \u043f\u043e\u044d\u0442\u0443 \u0421\u0438\u043c\u043e\u043d\u0438\u0434\u0443 \u041a\u0435\u043e\u0441\u0441\u043a\u043e\u043c\u0443, \u0436\u0438\u0432\u0448\u0435\u043c\u0443 \u043e\u043a\u043e\u043b\u043e 500 \u0433\u043e\u0434\u0430 \u0434\u043e \u043d. \u044d., \u043d\u043e \u0434\u043e\u0448\u0451\u043b \u044d\u0442\u043e\u0442 \u0441\u044e\u0436\u0435\u0442 \u0442\u043e\u043b\u044c\u043a\u043e \u0447\u0435\u0440\u0435\u0437 \u043f\u043e\u0437\u0434\u043d\u0435\u0435 \u0438\u0437\u043b\u043e\u0436\u0435\u043d\u0438\u0435 \u0426\u0438\u0446\u0435\u0440\u043e\u043d\u0430 \u0432 \u0442\u0440\u0430\u043a\u0442\u0430\u0442\u0435 \xab\u041e\u0431 \u043e\u0440\u0430\u0442\u043e\u0440\u0435\xbb (55 \u0433. \u0434\u043e \u043d. \u044d.), \u0442\u0430\u043a \u0447\u0442\u043e \u044d\u0442\u043e \u0441\u043a\u043e\u0440\u0435\u0435 \u043f\u0440\u0435\u0434\u0430\u043d\u0438\u0435, \u0447\u0435\u043c \u0442\u043e\u0447\u043d\u0430\u044f \u0438\u0441\u0442\u043e\u0440\u0438\u044f. \u0421\u0430\u043c\u043e \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u0435 \u2014 \u0441\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u0430\u044f \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0430 \u043d\u0430 \u043e\u0441\u043d\u043e\u0432\u0435 \u0434\u0440\u0435\u0432\u043d\u0435\u0439 \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u0438, \u0430 \u043d\u0435 \u0447\u044c\u0451-\u0442\u043e \u043b\u0438\u0447\u043d\u043e\u0435 \u0438\u0437\u043e\u0431\u0440\u0435\u0442\u0435\u043d\u0438\u0435.",methods:"\u041d\u0435 \u043f\u043e\u0432\u0442\u043e\u0440\u044f\u0439\u0442\u0435 \u044d\u043b\u0435\u043c\u0435\u043d\u0442\u044b \u043f\u043b\u043e\u0441\u043a\u0438\u043c \u0441\u043f\u0438\u0441\u043a\u043e\u043c \u2014 \u043f\u0440\u0435\u0432\u0440\u0430\u0449\u0430\u0439\u0442\u0435 \u043a\u0430\u0436\u0434\u044b\u0439 \u0432 \u044f\u0440\u043a\u0438\u0439, \u0447\u0443\u0442\u044c \u0430\u0431\u0441\u0443\u0440\u0434\u043d\u044b\u0439 \u043e\u0431\u0440\u0430\u0437 \u0438 \u0441\u0432\u044f\u0437\u044b\u0432\u0430\u0439\u0442\u0435 \u043e\u0431\u0440\u0430\u0437\u044b \u0432 \u0446\u0435\u043f\u043e\u0447\u043a\u0443 \u0438\u043b\u0438 \u0432 \u043f\u0440\u043e\u0433\u0443\u043b\u043a\u0443 \u043f\u043e \u0445\u043e\u0440\u043e\u0448\u043e \u0437\u043d\u0430\u043a\u043e\u043c\u043e\u043c\u0443 \u043c\u0435\u0441\u0442\u0443. \u0417\u0430\u043f\u043e\u043c\u0438\u043d\u0430\u0439\u0442\u0435 \u0432 \u043c\u043e\u043c\u0435\u043d\u0442, \u043a\u043e\u0433\u0434\u0430 \u0432\u043f\u0435\u0440\u0432\u044b\u0435 \u0432\u0438\u0434\u0438\u0442\u0435 \u044d\u043b\u0435\u043c\u0435\u043d\u0442, \u0430 \u043d\u0435 \u0432 \u0441\u0430\u043c\u043e\u043c \u043a\u043e\u043d\u0446\u0435; \u043f\u0440\u0435\u0443\u0432\u0435\u043b\u0438\u0447\u0438\u0432\u0430\u0439\u0442\u0435 \u0438 \u0434\u043e\u0431\u0430\u0432\u043b\u044f\u0439\u0442\u0435 \u0434\u0432\u0438\u0436\u0435\u043d\u0438\u0435, \u0447\u0442\u043e\u0431\u044b \u043e\u0431\u0440\u0430\u0437 \u0434\u0435\u0440\u0436\u0430\u043b\u0441\u044f; \u0430 \u043f\u0440\u0438 \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u0435\u0434\u0435\u043d\u0438\u0438 \u043f\u0440\u043e\u0445\u043e\u0434\u0438\u0442\u0435 \u0442\u043e\u0442 \u0436\u0435 \u043c\u0430\u0440\u0448\u0440\u0443\u0442 \u0438\u043b\u0438 \u0446\u0435\u043f\u043e\u0447\u043a\u0443 \u043f\u043e \u043f\u043e\u0440\u044f\u0434\u043a\u0443, \u0430 \u043d\u0435 \u0445\u0432\u0430\u0442\u0430\u0439\u0442\u0435 \u044d\u043b\u0435\u043c\u0435\u043d\u0442\u044b \u043d\u0430\u0443\u0433\u0430\u0434.",duration:"\u0427\u0430\u0441\u0442\u043e \u0438 \u043f\u043e\u043d\u0435\u043c\u043d\u043e\u0433\u0443 \u043b\u0443\u0447\u0448\u0435, \u0447\u0435\u043c \u0440\u0435\u0434\u043a\u043e \u0438 \u043f\u043e\u043c\u043d\u043e\u0433\u0443. \u0414\u043e\u0441\u0442\u0430\u0442\u043e\u0447\u043d\u043e 10\u201315 \u043c\u0438\u043d\u0443\u0442 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0440\u0430\u0437 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e, \u0447\u0442\u043e\u0431\u044b \u0437\u0430\u043a\u0440\u0435\u043f\u0438\u0442\u044c \u043f\u0440\u0438\u0432\u044b\u0447\u043a\u0443 \u043a\u043e\u0434\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u043e\u0431\u0440\u0430\u0437\u0430\u043c\u0438; \u043a\u0430\u0447\u0435\u0441\u0442\u0432\u043e \u043e\u0431\u0440\u0430\u0437\u043e\u0432 \u0432\u0430\u0436\u043d\u0435\u0435 \u043e\u0431\u0449\u0435\u0433\u043e \u0432\u0440\u0435\u043c\u0435\u043d\u0438, \u0442\u0430\u043a \u0447\u0442\u043e \u0437\u0430\u043a\u0430\u043d\u0447\u0438\u0432\u0430\u0439\u0442\u0435, \u043a\u0430\u043a \u0442\u043e\u043b\u044c\u043a\u043e \u043a\u0430\u0440\u0442\u0438\u043d\u043a\u0438 \u0441\u0442\u0430\u043d\u043e\u0432\u044f\u0442\u0441\u044f \u043b\u0435\u043d\u0438\u0432\u044b\u043c\u0438.",research:"\u0414\u043e\u043a\u0430\u0437\u0430\u043d\u043e \u0438\u043c\u0435\u043d\u043d\u043e \u0442\u043e, \u0447\u0435\u0433\u043e \u0438 \u0441\u0442\u043e\u0438\u0442 \u0436\u0434\u0430\u0442\u044c: \u043b\u044e\u0434\u0438, \u043e\u0431\u0443\u0447\u0435\u043d\u043d\u044b\u0435 \u0442\u0430\u043a\u043e\u043c\u0443 \u043e\u0431\u0440\u0430\u0437\u043d\u043e-\u043c\u0430\u0440\u0448\u0440\u0443\u0442\u043d\u043e\u043c\u0443 \u0437\u0430\u043f\u043e\u043c\u0438\u043d\u0430\u043d\u0438\u044e, \u0437\u0430\u043c\u0435\u0442\u043d\u043e \u043b\u0443\u0447\u0448\u0435 \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u044f\u0442 \u0443\u043f\u043e\u0440\u044f\u0434\u043e\u0447\u0435\u043d\u043d\u044b\u0435 \u0441\u043f\u0438\u0441\u043a\u0438, \u0430 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u0435 2017 \u0433\u043e\u0434\u0430 (\u0414\u0440\u0435\u0441\u043b\u0435\u0440 \u0441 \u043a\u043e\u043b\u043b\u0435\u0433\u0430\u043c\u0438) \u043f\u043e\u043a\u0430\u0437\u0430\u043b\u043e, \u0447\u0442\u043e \u0448\u0435\u0441\u0442\u044c \u043d\u0435\u0434\u0435\u043b\u044c \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0438 \u043f\u043e \u043c\u0435\u0442\u043e\u0434\u0443 \u043b\u043e\u043a\u0443\u0441\u043e\u0432 \u043f\u0440\u0438\u043c\u0435\u0440\u043d\u043e \u0443\u0434\u0432\u043e\u0438\u043b\u0438 \u043e\u0431\u044a\u0451\u043c \u0437\u0430\u043f\u043e\u043c\u0438\u043d\u0430\u043d\u0438\u044f \u0443 \u043d\u043e\u0432\u0438\u0447\u043a\u043e\u0432 \u0438 \u0441\u0434\u0432\u0438\u043d\u0443\u043b\u0438 \u0441\u0432\u044f\u0437\u0438 \u0432 \u0438\u0445 \u043c\u043e\u0437\u0433\u0435 \u0432 \u0441\u0442\u043e\u0440\u043e\u043d\u0443 \u043f\u0440\u043e\u0444\u0438\u043b\u044f \u0442\u043e\u043f\u043e\u0432\u044b\u0445 \u0430\u0442\u043b\u0435\u0442\u043e\u0432 \u043f\u0430\u043c\u044f\u0442\u0438. \u0421\u043b\u0430\u0431\u0435\u0435 \u043e\u0431\u0441\u0442\u043e\u0438\u0442 \u0434\u0435\u043b\u043e \u0441 \u0448\u0438\u0440\u043e\u043a\u0438\u043c\u0438 \u0437\u0430\u044f\u0432\u043b\u0435\u043d\u0438\u044f\u043c\u0438: \u043a\u0440\u0443\u043f\u043d\u044b\u0435 \u043c\u0435\u0442\u0430-\u0430\u043d\u0430\u043b\u0438\u0437\u044b \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043e\u043a \u043f\u0430\u043c\u044f\u0442\u0438 \u043f\u043e\u0447\u0442\u0438 \u043d\u0435 \u043d\u0430\u0445\u043e\u0434\u044f\u0442 \u043d\u0430\u0434\u0451\u0436\u043d\u043e\u0433\u043e \xab\u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0430\xbb \u043d\u0430 \u043e\u0431\u0449\u0438\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0438\u043b\u0438 \u043f\u043e\u0432\u0441\u0435\u0434\u043d\u0435\u0432\u043d\u043e\u0435 \u043c\u044b\u0448\u043b\u0435\u043d\u0438\u0435, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u043a \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f\u043c \xab\u043f\u043e\u0434\u043d\u044f\u0442\u044c IQ\xbb \u0438\u043b\u0438 \xab\u043f\u0440\u043e\u043a\u0430\u0447\u0430\u0442\u044c \u0443\u043c \u0432 \u0446\u0435\u043b\u043e\u043c\xbb \u0441\u0442\u043e\u0438\u0442 \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u044c\u0441\u044f \u043e\u0441\u0442\u043e\u0440\u043e\u0436\u043d\u043e. \u041f\u043e \u0441\u0443\u0442\u0438 \u0432\u044b \u043f\u043e\u043b\u0443\u0447\u0430\u0435\u0442\u0435 \u043c\u043e\u0449\u043d\u044b\u0439 \u043d\u0430\u0432\u044b\u043a, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u043c\u043e\u0436\u043d\u043e \u0432\u044b\u0443\u0447\u0438\u0442\u044c, \u0434\u043b\u044f \u0437\u0430\u043f\u043e\u043c\u0438\u043d\u0430\u043d\u0438\u044f \u0442\u043e\u0433\u043e \u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u0430, \u0447\u0442\u043e \u0441\u0430\u043c\u0438 \u0440\u0435\u0448\u0438\u043b\u0438 \u0437\u0430\u043a\u043e\u0434\u0438\u0440\u043e\u0432\u0430\u0442\u044c.",rec:"\u0412\u044b\u0431\u0435\u0440\u0438\u0442\u0435 \u043e\u0434\u0438\u043d \u0437\u043d\u0430\u043a\u043e\u043c\u044b\u0439 \u043c\u0430\u0440\u0448\u0440\u0443\u0442 \u2014 \u043a\u0432\u0430\u0440\u0442\u0438\u0440\u0443, \u0434\u043e\u0440\u043e\u0433\u0443 \u043d\u0430 \u0440\u0430\u0431\u043e\u0442\u0443 \u2014 \u0438 \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0439\u0442\u0435 \u0435\u0433\u043e \u043a\u0430\u0436\u0434\u044b\u0439 \u0440\u0430\u0437; \u0443\u0441\u0442\u043e\u0439\u0447\u0438\u0432\u0430\u044f, \u0445\u043e\u0436\u0435\u043d\u0430\u044f \u0442\u0440\u043e\u043f\u0430 \u0434\u0435\u0440\u0436\u0438\u0442 \u043f\u0430\u043c\u044f\u0442\u044c \u043b\u0443\u0447\u0448\u0435, \u0447\u0435\u043c \u043d\u043e\u0432\u0430\u044f \u043a\u0440\u0430\u0441\u0438\u0432\u0430\u044f \u043d\u0430 \u043a\u0430\u0436\u0434\u043e\u043c \u043f\u043e\u0434\u0445\u043e\u0434\u0435.",faq:[["\u0423\u043b\u0443\u0447\u0448\u0438\u0442 \u043b\u0438 \u044d\u0442\u043e \u043c\u043e\u044e \u043f\u0430\u043c\u044f\u0442\u044c \u0432 \u043e\u0431\u044b\u0447\u043d\u043e\u0439 \u0436\u0438\u0437\u043d\u0438?","\u041e\u043d\u043e \u043d\u0430\u0434\u0451\u0436\u043d\u043e \u0443\u043b\u0443\u0447\u0448\u0430\u0435\u0442 \u0437\u0430\u043f\u043e\u043c\u0438\u043d\u0430\u043d\u0438\u0435 \u0442\u043e\u0433\u043e, \u0447\u0442\u043e \u0432\u044b \u043d\u0430\u043c\u0435\u0440\u0435\u043d\u043d\u043e \u043a\u043e\u0434\u0438\u0440\u0443\u0435\u0442\u0435 \u044d\u0442\u0438\u043c \u043f\u0440\u0438\u0451\u043c\u043e\u043c, \u2014 \u0441\u043f\u0438\u0441\u043a\u043e\u0432, \u0438\u043c\u0451\u043d, \u0440\u0435\u0447\u0435\u0439. \u0410 \u0432\u043e\u0442 \u0442\u043e, \u0447\u0442\u043e \u043e\u043d\u043e \u043f\u043e\u0432\u044b\u0448\u0430\u0435\u0442 \u043f\u0430\u043c\u044f\u0442\u044c \u0438\u043b\u0438 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \xab\u0432\u043e\u043e\u0431\u0449\u0435\xbb, \u0434\u043e\u043a\u0430\u0437\u0430\u043d\u043e \u043a\u0443\u0434\u0430 \u0441\u043b\u0430\u0431\u0435\u0435, \u0442\u0430\u043a \u0447\u0442\u043e \u0441\u0447\u0438\u0442\u0430\u0439\u0442\u0435 \u044d\u0442\u043e \u0438\u043d\u0441\u0442\u0440\u0443\u043c\u0435\u043d\u0442\u043e\u043c, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u043f\u0440\u0438\u043c\u0435\u043d\u044f\u044e\u0442, \u0430 \u043d\u0435 \u0430\u043f\u0433\u0440\u0435\u0439\u0434\u043e\u043c \u043c\u043e\u0437\u0433\u0430."],["\u0423 \u043c\u0435\u043d\u044f \u043f\u043b\u043e\u0445\u043e \u0441 \u0432\u043e\u043e\u0431\u0440\u0430\u0436\u0435\u043d\u0438\u0435\u043c \u2014 \u043c\u043d\u0435 \u044d\u0442\u043e \u043f\u043e\u0434 \u0441\u0438\u043b\u0443?","\u0414\u0430. \u042f\u0440\u043a\u043e\u0441\u0442\u044c \u0440\u0430\u0441\u0442\u0451\u0442 \u0441 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u043e\u0439, \u0438 \u043c\u043e\u0436\u043d\u043e \u043e\u043f\u0438\u0440\u0430\u0442\u044c\u0441\u044f \u043d\u0430 \u0434\u0440\u0443\u0433\u0438\u0435 \u0447\u0443\u0432\u0441\u0442\u0432\u0430, \u043d\u0430 \u0438\u0441\u0442\u043e\u0440\u0438\u044e, \u0441\u0432\u044f\u0437\u044b\u0432\u0430\u044e\u0449\u0443\u044e \u044d\u043b\u0435\u043c\u0435\u043d\u0442\u044b, \u0438\u043b\u0438 \u043d\u0430 \u0437\u043d\u0430\u043a\u043e\u043c\u044b\u0439 \u043c\u0430\u0440\u0448\u0440\u0443\u0442. \u041e\u0431\u0440\u0430\u0437\u044b \u0434\u043e\u043b\u0436\u043d\u044b \u0447\u0442\u043e-\u0442\u043e \u0437\u043d\u0430\u0447\u0438\u0442\u044c \u0438\u043c\u0435\u043d\u043d\u043e \u0434\u043b\u044f \u0432\u0430\u0441, \u043a\u0438\u043d\u0435\u043c\u0430\u0442\u043e\u0433\u0440\u0430\u0444\u0438\u0447\u043d\u044b\u043c\u0438 \u0431\u044b\u0442\u044c \u043d\u0435 \u043e\u0431\u044f\u0437\u0430\u043d\u044b."],["\u0417\u0430\u0447\u0435\u043c \u044d\u0442\u043e, \u0435\u0441\u043b\u0438 \u043c\u043e\u0436\u043d\u043e \u043f\u0440\u043e\u0441\u0442\u043e \u0437\u0430\u043f\u0438\u0441\u0430\u0442\u044c \u0441\u043f\u0438\u0441\u043e\u043a?","\u0414\u043b\u044f \u0431\u044b\u0442\u043e\u0432\u044b\u0445 \u0437\u0430\u0434\u0430\u0447 \u0437\u0430\u043f\u0438\u0441\u0430\u0442\u044c \u043e\u0431\u044b\u0447\u043d\u043e \u0438 \u043f\u0440\u0430\u0432\u0434\u0430 \u0440\u0430\u0437\u0443\u043c\u043d\u0435\u0435. \u042d\u0442\u043e \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u0435 \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u0441\u0430\u043c \u043d\u0430\u0432\u044b\u043a \u0443\u043f\u043e\u0440\u044f\u0434\u043e\u0447\u0435\u043d\u043d\u043e\u0433\u043e \u0430\u0441\u0441\u043e\u0446\u0438\u0430\u0442\u0438\u0432\u043d\u043e\u0433\u043e \u0437\u0430\u043f\u043e\u043c\u0438\u043d\u0430\u043d\u0438\u044f \u2014 \u043e\u043d \u043f\u0440\u0438\u0433\u043e\u0434\u0438\u0442\u0441\u044f, \u043a\u043e\u0433\u0434\u0430 \u0437\u0430\u043f\u0438\u0441\u0430\u0442\u044c \u043d\u0435\u043b\u044c\u0437\u044f, \u043a\u043e\u0433\u0434\u0430 \u043d\u0443\u0436\u043d\u043e \u0432\u0441\u043f\u043e\u043c\u0438\u043d\u0430\u0442\u044c \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u0438\u043b\u0438 \u043a\u043e\u0433\u0434\u0430 \u0432\u044b \u043f\u0440\u043e\u0441\u0442\u043e \u0445\u043e\u0442\u0438\u0442\u0435 \u0431\u043e\u043b\u0435\u0435 \u043a\u0440\u0435\u043f\u043a\u0443\u044e \u0438 \u0433\u0438\u0431\u043a\u0443\u044e \u043f\u0430\u043c\u044f\u0442\u044c."]],variants:"\u0421\u0440\u0435\u0434\u0438 \u0432\u0430\u0440\u0438\u0430\u0446\u0438\u0439 \u2014 \u043c\u0435\u0442\u043e\u0434 \u043b\u043e\u043a\u0443\u0441\u043e\u0432 (\u0440\u0430\u0441\u0441\u0442\u0430\u0432\u043b\u044f\u0442\u044c \u044d\u043b\u0435\u043c\u0435\u043d\u0442\u044b \u0432\u0434\u043e\u043b\u044c \u0437\u0430\u043f\u043e\u043c\u043d\u0435\u043d\u043d\u043e\u0433\u043e \u043c\u0430\u0440\u0448\u0440\u0443\u0442\u0430), \u043c\u0435\u0442\u043e\u0434 \u0441\u0432\u044f\u0437\u043e\u043a \u0438\u043b\u0438 \u0438\u0441\u0442\u043e\u0440\u0438\u0439 (\u0441\u0446\u0435\u043f\u043b\u044f\u0442\u044c \u044d\u043b\u0435\u043c\u0435\u043d\u0442\u044b \u0432 \u043f\u043e\u0432\u0435\u0441\u0442\u0432\u043e\u0432\u0430\u043d\u0438\u0435), \u0441\u0438\u0441\u0442\u0435\u043c\u0430 \u043e\u043f\u043e\u0440 (\u0432\u0435\u0448\u0430\u0442\u044c \u044d\u043b\u0435\u043c\u0435\u043d\u0442\u044b \u043d\u0430 \u0437\u0430\u0440\u0430\u043d\u0435\u0435 \u0437\u0430\u0434\u0430\u043d\u043d\u044b\u0439 \u043d\u0443\u043c\u0435\u0440\u043e\u0432\u0430\u043d\u043d\u044b\u0439 \u0441\u043f\u0438\u0441\u043e\u043a), \u0430 \u0442\u0430\u043a\u0436\u0435 \u0443\u0441\u043b\u043e\u0436\u043d\u0451\u043d\u043d\u044b\u0435 \u0440\u0435\u0436\u0438\u043c\u044b, \u0433\u0434\u0435 \u043f\u043e\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c \u0434\u043b\u0438\u043d\u043d\u0435\u0435, \u0432\u0440\u0435\u043c\u044f \u043f\u043e\u043a\u0430\u0437\u0430 \u043a\u043e\u0440\u043e\u0447\u0435 \u0438\u043b\u0438 \u043f\u043e\u0434\u043c\u0435\u0448\u0430\u043d\u044b \u0430\u0431\u0441\u0442\u0440\u0430\u043a\u0442\u043d\u044b\u0435 \u0441\u0438\u043c\u0432\u043e\u043b\u044b \u0438 \u0446\u0438\u0444\u0440\u044b."},en:{about:"Mnemonics: Sequence shows you a short ordered list of items, then asks you to reproduce them in the exact same order. The point is not to stare and repeat, but to link each item to the next with a vivid mental image or a route through a familiar place, so the order is carried by associations rather than by raw effort.",benefit:"It trains deliberate, associative encoding and ordered recall: your ability to hold a sequence, attach meaning to otherwise arbitrary items, and play them back in the right order. With practice it also builds the habit of converting abstract material into concrete images.",history:"The underlying idea is one of the oldest documented memory aids in the Western tradition, the 'art of memory'. It was prized by Greek and Roman orators for memorising long speeches, passed through medieval and Renaissance treatises, and survives today in competitive memory sports, where athletes use it to memorise card decks and long digit strings.",creator:"There is no single inventor. The technique is traditionally attributed to the Greek poet Simonides of Ceos around 500 BCE, but that story comes to us only through Cicero's later account in De Oratore (55 BCE), so it is legend as much as history. The exercise here is a modern drill built on that ancient tradition, not the invention of any one person.",methods:"Don't rehearse items as a flat list; turn each one into a striking, slightly absurd image and connect images into a chain or a walk through a place you know well. Encode in the moment you first see an item rather than at the end, exaggerate and add motion to make images stick, and when you recall, retrace the same route or chain in order instead of grabbing items at random.",duration:"Short and frequent beats long and rare. Ten to fifteen minutes a few times a week is enough to build the encoding habit; quality of imagery matters far more than total time, so stop once your images get lazy.",research:"Evidence is strong for exactly what you would expect \u2014 people trained in this kind of imagery and route-based method recall ordered lists far better, and a 2017 study (Dresler and colleagues) showed six weeks of method-of-loci training roughly doubled recall in beginners and shifted their brain connectivity toward that of elite memory athletes. The weaker claims are the broad ones: large meta-analyses of memory training find little reliable 'far transfer' to general intelligence or everyday cognition, so treat promises of a higher IQ or all-round sharper mind with caution. What you mainly get is a powerful, learnable skill for memorising material you choose to encode.",rec:"Pick one familiar route \u2014 your home, your commute \u2014 and reuse it every session; a stable, well-worn path is a better memory aid than a fancy new one each time.",faq:[["Will this make my everyday memory better?","It reliably makes you better at memorising things you deliberately encode with the technique, like lists, names or speeches. It is far less proven that it sharpens general memory or intelligence across the board, so think of it as a tool you apply, not a brain upgrade."],["I'm bad at picturing things \u2014 can I still do it?","Yes. Vividness improves with practice, and you can lean on other senses, on a story that links the items, or on a familiar route. The images only need to mean something to you; they do not have to be cinematic."],["Why bother when I can just write a list down?","For everyday tasks, writing it down is usually smarter. This exercise trains the underlying skill of ordered, associative recall, which is useful when you can't take notes, want faster retrieval, or simply want a stronger, more flexible memory."]],variants:"Variations include the method of loci (placing items along a remembered route), the linking or story method (chaining each item to the next in a narrative), the peg system (hooking items onto a fixed numbered list), and harder modes that lengthen the sequence, shorten the viewing time, or mix in abstract symbols and digits."},es:{about:"Mnemotecnia: Secuencia te muestra una lista ordenada y breve de elementos y luego te pide reproducirlos exactamente en el mismo orden. La clave no es mirar fijamente y repetir, sino enlazar cada elemento con el siguiente mediante una imagen mental v\xedvida o un recorrido por un lugar conocido, de modo que el orden lo sostengan las asociaciones y no el esfuerzo bruto.",benefit:"Entrena la codificaci\xf3n asociativa deliberada y el recuerdo ordenado: tu capacidad de retener una secuencia, dar sentido a elementos por lo dem\xe1s arbitrarios y reproducirlos en el orden correcto. Con la pr\xe1ctica tambi\xe9n construye el h\xe1bito de convertir el material abstracto en im\xe1genes concretas.",history:"La idea de fondo es una de las ayudas para la memoria m\xe1s antiguas documentadas en la tradici\xf3n occidental, el 'arte de la memoria'. La apreciaban los oradores griegos y romanos para memorizar discursos largos, pas\xf3 por los tratados medievales y renacentistas, y sobrevive hoy en los deportes de memoria de competici\xf3n, donde los atletas la usan para memorizar barajas de cartas y largas cadenas de d\xedgitos.",creator:"No hay un \xfanico inventor. La t\xe9cnica se atribuye tradicionalmente al poeta griego Sim\xf3nides de Ceos, hacia el 500 a. C., pero esa historia nos llega solo a trav\xe9s del relato posterior de Cicer\xf3n en De Oratore (55 a. C.), as\xed que es tanto leyenda como historia. El ejercicio que ves aqu\xed es una pr\xe1ctica moderna construida sobre esa tradici\xf3n antigua, no la invenci\xf3n de una sola persona.",methods:"No repases los elementos como una lista plana; convierte cada uno en una imagen llamativa y algo absurda y conecta las im\xe1genes en una cadena o en un paseo por un lugar que conozcas bien. Codifica en el momento en que ves un elemento por primera vez, no al final; exagera y a\xf1ade movimiento para que las im\xe1genes se fijen, y cuando recuerdes, vuelve a recorrer la misma ruta o cadena en orden en lugar de tomar elementos al azar.",duration:"Poco y a menudo vence a mucho y de tarde en tarde. De diez a quince minutos unas pocas veces por semana bastan para construir el h\xe1bito de codificaci\xf3n; la calidad de las im\xe1genes importa mucho m\xe1s que el tiempo total, as\xed que detente en cuanto tus im\xe1genes se vuelvan perezosas.",research:"La evidencia es s\xf3lida justo en lo que cabr\xeda esperar: las personas entrenadas en este tipo de m\xe9todo basado en im\xe1genes y recorridos recuerdan mucho mejor las listas ordenadas, y un estudio de 2017 (Dresler y colaboradores) mostr\xf3 que seis semanas de entrenamiento con el m\xe9todo de los loci aproximadamente duplicaron el recuerdo en principiantes y desplazaron su conectividad cerebral hacia la de los atletas de memoria de \xe9lite. Las afirmaciones m\xe1s d\xe9biles son las amplias: los grandes metaan\xe1lisis del entrenamiento de la memoria encuentran poca 'transferencia lejana' fiable a la inteligencia general o a la cognici\xf3n cotidiana, as\xed que toma con cautela las promesas de un CI m\xe1s alto o de una mente m\xe1s aguda en todo. Lo que sobre todo obtienes es una destreza poderosa y aprendible para memorizar el material que eliges codificar.",rec:"Elige una ruta familiar -tu casa, tu trayecto al trabajo- y reutil\xedzala en cada sesi\xf3n; un camino estable y muy transitado es mejor ayuda para la memoria que uno nuevo y rebuscado cada vez.",faq:[["\xbfEsto mejorar\xe1 mi memoria cotidiana?","De forma fiable te hace mejor memorizando cosas que codificas a prop\xf3sito con la t\xe9cnica, como listas, nombres o discursos. Est\xe1 mucho menos demostrado que agudice la memoria o la inteligencia general en su conjunto, as\xed que piensa en ello como una herramienta que aplicas, no como una mejora del cerebro."],["Se me da mal imaginar cosas, \xbfaun as\xed puedo hacerlo?","S\xed. La viveza mejora con la pr\xe1ctica, y puedes apoyarte en otros sentidos, en una historia que enlace los elementos o en una ruta familiar. Las im\xe1genes solo necesitan significar algo para ti; no tienen que ser cinematogr\xe1ficas."],["\xbfPara qu\xe9 molestarse si puedo apuntar una lista?","Para las tareas cotidianas, apuntarla suele ser m\xe1s inteligente. Este ejercicio entrena la destreza de fondo del recuerdo ordenado y asociativo, que es \xfatil cuando no puedes tomar notas, quieres recuperar la informaci\xf3n m\xe1s r\xe1pido o simplemente quieres una memoria m\xe1s fuerte y flexible."]],variants:"Las variantes incluyen el m\xe9todo de los loci (colocar elementos a lo largo de un recorrido recordado), el m\xe9todo del enlace o de la historia (encadenar cada elemento al siguiente en una narraci\xf3n), el sistema de perchas (enganchar elementos a una lista numerada fija) y modos m\xe1s dif\xedciles que alargan la secuencia, acortan el tiempo de visualizaci\xf3n o mezclan s\xedmbolos abstractos y d\xedgitos."},de:{about:"Mnemonics: Sequence zeigt dir eine kurze geordnete Liste von Elementen und verlangt dann, sie in genau derselben Reihenfolge wiederzugeben. Es geht nicht ums Anstarren und Wiederholen, sondern darum, jedes Element mit dem n\xe4chsten \xfcber ein lebhaftes inneres Bild oder einen Weg durch einen vertrauten Ort zu verkn\xfcpfen, sodass die Reihenfolge von Assoziationen getragen wird statt von roher Anstrengung.",benefit:"Es trainiert das bewusste, assoziative Einpr\xe4gen und den geordneten Abruf: deine F\xe4higkeit, eine Reihenfolge zu halten, ansonsten willk\xfcrlichen Elementen Bedeutung zu geben und sie in der richtigen Ordnung wiederzugeben. Mit \xdcbung w\xe4chst auch die Gewohnheit, abstraktes Material in konkrete Bilder zu \xfcbersetzen.",history:"Die zugrunde liegende Idee ist eines der \xe4ltesten dokumentierten Ged\xe4chtnishilfsmittel der westlichen Tradition, die \u201eGed\xe4chtniskunst\u201c. Griechische und r\xf6mische Redner sch\xe4tzten sie zum Auswendiglernen langer Reden, sie zog sich durch mittelalterliche und Renaissance-Abhandlungen und \xfcberlebt heute im Ged\xe4chtnissport, wo Athleten damit Kartenstapel und lange Ziffernfolgen einpr\xe4gen.",creator:"Es gibt keinen einzelnen Erfinder. Die Technik wird traditionell dem griechischen Dichter Simonides von Keos um 500 v. Chr. zugeschrieben, doch diese Geschichte erreicht uns nur \xfcber Ciceros sp\xe4teren Bericht in De Oratore (55 v. Chr.) \u2013 sie ist also ebenso Legende wie Geschichte. Die \xdcbung hier ist eine moderne Anwendung, die auf dieser alten Tradition aufbaut, nicht die Erfindung einer einzelnen Person.",methods:"\xdcbe die Elemente nicht als flache Liste ein; verwandle jedes in ein auff\xe4lliges, leicht absurdes Bild und verbinde die Bilder zu einer Kette oder einem Gang durch einen Ort, den du gut kennst. Pr\xe4ge im Moment ein, in dem du ein Element zuerst siehst, nicht erst am Ende; \xfcbertreibe und f\xfcge Bewegung hinzu, damit die Bilder haften; und gehe beim Abrufen denselben Weg oder dieselbe Kette der Reihe nach erneut durch, statt Elemente aufs Geratewohl herauszugreifen.",duration:"Kurz und h\xe4ufig schl\xe4gt lang und selten. Zehn bis f\xfcnfzehn Minuten ein paar Mal pro Woche reichen, um die Einpr\xe4ge-Gewohnheit aufzubauen; die Qualit\xe4t der Bilder z\xe4hlt weit mehr als die Gesamtzeit \u2013 h\xf6r also auf, sobald deine Bilder nachl\xe4ssig werden.",research:"Die Belege sind stark f\xfcr genau das, was man erwarten w\xfcrde: Wer in dieser bild- und routengest\xfctzten Methode ge\xfcbt ist, ruft geordnete Listen weit besser ab, und eine Studie von 2017 (Dresler und Kollegen) zeigte, dass sechs Wochen Training mit der Loci-Methode den Abruf bei Anf\xe4ngern etwa verdoppelte und ihre Hirnvernetzung in Richtung der von Spitzen-Ged\xe4chtnisathleten verschob. Schw\xe4cher sind die breiten Behauptungen: Gro\xdfe Meta-Analysen zum Ged\xe4chtnistraining finden kaum verl\xe4sslichen \u201eFerntransfer\u201c auf allgemeine Intelligenz oder allt\xe4gliche Kognition \u2013 Versprechen eines h\xf6heren IQ oder eines rundum sch\xe4rferen Verstandes also mit Vorsicht genie\xdfen. Was du vor allem bekommst, ist eine kraftvolle, erlernbare Fertigkeit zum Einpr\xe4gen von Material, das du gezielt zu kodieren w\xe4hlst.",rec:"W\xe4hle einen vertrauten Weg \u2013 deine Wohnung, deinen Arbeitsweg \u2013 und nutze ihn jede Sitzung wieder; ein stabiler, gut eingelaufener Pfad ist eine bessere Ged\xe4chtnishilfe als jedes Mal ein ausgefallener neuer.",faq:[["Macht das mein allt\xe4gliches Ged\xe4chtnis besser?","Es macht dich verl\xe4sslich besser darin, Dinge einzupr\xe4gen, die du mit der Technik bewusst kodierst, etwa Listen, Namen oder Reden. Weit weniger belegt ist, dass es das Ged\xe4chtnis oder die Intelligenz auf ganzer Linie sch\xe4rft \u2013 betrachte es also als Werkzeug, das du anwendest, nicht als Gehirn-Upgrade."],["Ich kann mir Dinge schlecht bildlich vorstellen \u2013 geht das trotzdem?","Ja. Die Lebendigkeit verbessert sich mit \xdcbung, und du kannst dich auf andere Sinne st\xfctzen, auf eine Geschichte, die die Elemente verbindet, oder auf einen vertrauten Weg. Die Bilder m\xfcssen dir nur etwas bedeuten; sie m\xfcssen nicht filmreif sein."],["Wozu der Aufwand, wenn ich mir einfach eine Liste aufschreiben kann?","F\xfcr allt\xe4gliche Aufgaben ist Aufschreiben meist kl\xfcger. Diese \xdcbung trainiert die zugrunde liegende Fertigkeit des geordneten, assoziativen Abrufs, die n\xfctzlich ist, wenn du dir keine Notizen machen kannst, schneller abrufen willst oder schlicht ein st\xe4rkeres, flexibleres Ged\xe4chtnis w\xfcnschst."]],variants:"Zu den Variationen z\xe4hlen die Loci-Methode (Elemente entlang eines erinnerten Weges platzieren), die Verkn\xfcpfungs- oder Geschichtenmethode (jedes Element in einer Erz\xe4hlung an das n\xe4chste ketten), das Pegsystem (Elemente an eine feste nummerierte Liste h\xe4ngen) sowie schwerere Modi, die die Reihenfolge verl\xe4ngern, die Anzeigezeit verk\xfcrzen oder abstrakte Symbole und Ziffern beimischen."},pt:{about:"Mnemonics: Sequence mostra a voc\xea uma lista curta e ordenada de itens e depois pede que voc\xea os reproduza exatamente na mesma ordem. A ideia n\xe3o \xe9 encarar e repetir, mas ligar cada item ao seguinte com uma imagem mental v\xedvida ou um percurso por um lugar conhecido, de modo que a ordem seja sustentada por associa\xe7\xf5es, e n\xe3o por esfor\xe7o puro.",benefit:"Treina a codifica\xe7\xe3o associativa e deliberada e a recorda\xe7\xe3o ordenada: sua capacidade de segurar uma sequ\xeancia, dar sentido a itens que de outro modo seriam arbitr\xe1rios e reproduzi-los na ordem certa. Com a pr\xe1tica, tamb\xe9m cria o h\xe1bito de converter material abstrato em imagens concretas.",history:"A ideia por tr\xe1s disso \xe9 um dos aux\xedlios de mem\xf3ria mais antigos documentados na tradi\xe7\xe3o ocidental, a \"arte da mem\xf3ria\". Era valorizada pelos oradores gregos e romanos para memorizar discursos longos, passou pelos tratados medievais e renascentistas e sobrevive hoje nos esportes competitivos de mem\xf3ria, em que os atletas a usam para memorizar baralhos e longas sequ\xeancias de d\xedgitos.",creator:"N\xe3o h\xe1 um \xfanico inventor. A t\xe9cnica \xe9 tradicionalmente atribu\xedda ao poeta grego Sim\xf4nides de Ceos, por volta de 500 a.C., mas essa hist\xf3ria chega at\xe9 n\xf3s apenas pelo relato posterior de C\xedcero em De Oratore (55 a.C.), de modo que \xe9 tanto lenda quanto hist\xf3ria. O exerc\xedcio aqui \xe9 um treino moderno constru\xeddo sobre essa tradi\xe7\xe3o antiga, n\xe3o a inven\xe7\xe3o de uma pessoa espec\xedfica.",methods:"N\xe3o decore os itens como uma lista plana; transforme cada um numa imagem marcante e um pouco absurda e conecte as imagens numa corrente ou num passeio por um lugar que voc\xea conhece bem. Codifique no momento em que v\xea o item pela primeira vez, e n\xe3o no fim, exagere e acrescente movimento para fazer as imagens grudarem, e, ao recordar, refa\xe7a o mesmo percurso ou a mesma corrente em ordem, em vez de pegar itens ao acaso.",duration:"Curto e frequente vence longo e raro. Dez a quinze minutos algumas vezes por semana bastam para construir o h\xe1bito de codifica\xe7\xe3o; a qualidade das imagens importa muito mais do que o tempo total, ent\xe3o pare assim que suas imagens ficarem pregui\xe7osas.",research:"A evid\xeancia \xe9 forte exatamente para o que se esperaria: pessoas treinadas nesse tipo de m\xe9todo baseado em imagens e percursos recordam listas ordenadas muito melhor, e um estudo de 2017 (Dresler e colegas) mostrou que seis semanas de treino no m\xe9todo de loci praticamente dobraram a recorda\xe7\xe3o em iniciantes e aproximaram sua conectividade cerebral da de atletas de mem\xf3ria de elite. As alega\xe7\xf5es mais fracas s\xe3o as amplas: grandes meta-an\xe1lises de treino de mem\xf3ria encontram pouca \"transfer\xeancia ampla\" confi\xe1vel para a intelig\xeancia geral ou a cogni\xe7\xe3o do dia a dia, ent\xe3o encare as promessas de um QI mais alto ou de uma mente mais afiada em geral com cautela. O que voc\xea ganha, sobretudo, \xe9 uma habilidade poderosa e aprend\xedvel para memorizar o material que voc\xea escolhe codificar.",rec:"Escolha um percurso familiar \u2014 sua casa, seu trajeto ao trabalho \u2014 e reutilize-o em toda sess\xe3o; um caminho est\xe1vel e bem conhecido \xe9 um aux\xedlio de mem\xf3ria melhor do que um novo e sofisticado a cada vez.",faq:[["Isso vai melhorar minha mem\xf3ria no dia a dia?","Ele melhora de forma confi\xe1vel sua capacidade de memorizar coisas que voc\xea codifica de prop\xf3sito com a t\xe9cnica, como listas, nomes ou discursos. \xc9 bem menos comprovado que aguce a mem\xf3ria ou a intelig\xeancia de modo geral, ent\xe3o pense nele como uma ferramenta que voc\xea aplica, e n\xe3o como uma melhoria do c\xe9rebro."],["Sou ruim em imaginar coisas \u2014 ainda assim consigo?","Sim. A vivacidade melhora com a pr\xe1tica, e voc\xea pode se apoiar em outros sentidos, numa hist\xf3ria que ligue os itens ou num percurso familiar. As imagens s\xf3 precisam significar algo para voc\xea; n\xe3o t\xeam de ser cinematogr\xe1ficas."],["Por que me dar esse trabalho se posso simplesmente anotar uma lista?","Para tarefas do dia a dia, anotar costuma ser mais esperto. Este exerc\xedcio treina a habilidade subjacente de recorda\xe7\xe3o ordenada e associativa, \xfatil quando voc\xea n\xe3o pode anotar, quer recuperar a informa\xe7\xe3o mais r\xe1pido ou simplesmente quer uma mem\xf3ria mais forte e flex\xedvel."]],variants:"As varia\xe7\xf5es incluem o m\xe9todo de loci (colocar os itens ao longo de um percurso lembrado), o m\xe9todo de liga\xe7\xe3o ou de hist\xf3ria (encadear cada item ao seguinte numa narrativa), o sistema de pinos (pendurar os itens em uma lista numerada fixa) e modos mais dif\xedceis que alongam a sequ\xeancia, encurtam o tempo de visualiza\xe7\xe3o ou misturam s\xedmbolos abstratos e d\xedgitos."},hi:{about:"\u0928\u0947\u092e\u0949\u0928\u093f\u0915\u094d\u0938: \u0938\u0940\u0915\u094d\u0935\u0947\u0902\u0938 \u0906\u092a\u0915\u094b \u091a\u0940\u091c\u093c\u094b\u0902 \u0915\u0940 \u090f\u0915 \u091b\u094b\u091f\u0940 \u0915\u094d\u0930\u092e\u092c\u0926\u094d\u0927 \u0938\u0942\u091a\u0940 \u0926\u093f\u0916\u093e\u0924\u093e \u0939\u0948, \u092b\u093f\u0930 \u0909\u0928\u094d\u0939\u0947\u0902 \u0920\u0940\u0915 \u0909\u0938\u0940 \u0915\u094d\u0930\u092e \u092e\u0947\u0902 \u0926\u094b\u092c\u093e\u0930\u093e \u092c\u0924\u093e\u0928\u0947 \u0915\u094b \u0915\u0939\u0924\u093e \u0939\u0948\u0964 \u092e\u0915\u0938\u0926 \u0918\u0942\u0930\u0915\u0930 \u0930\u091f\u0928\u093e \u0928\u0939\u0940\u0902 \u0939\u0948, \u092c\u0932\u094d\u0915\u093f \u0939\u0930 \u091a\u0940\u091c\u093c \u0915\u094b \u0905\u0917\u0932\u0940 \u0938\u0947 \u0915\u093f\u0938\u0940 \u091c\u0940\u0935\u0902\u0924 \u092e\u093e\u0928\u0938\u093f\u0915 \u091a\u093f\u0924\u094d\u0930 \u092f\u093e \u0915\u093f\u0938\u0940 \u091c\u093e\u0928\u0940-\u092a\u0939\u091a\u093e\u0928\u0940 \u091c\u0917\u0939 \u0915\u0947 \u0930\u093e\u0938\u094d\u0924\u0947 \u0938\u0947 \u091c\u094b\u0921\u093c\u0928\u093e \u0939\u0948, \u0924\u093e\u0915\u093f \u0915\u094d\u0930\u092e \u0915\u094b\u0930\u0940 \u092e\u0947\u0939\u0928\u0924 \u0938\u0947 \u0928\u0939\u0940\u0902 \u092c\u0932\u094d\u0915\u093f \u091c\u0941\u0921\u093c\u093e\u0935\u094b\u0902 \u0915\u0947 \u0938\u0939\u093e\u0930\u0947 \u091f\u093f\u0915\u093e \u0930\u0939\u0947\u0964",benefit:"\u092f\u0939 \u0938\u094b\u091a-\u0938\u092e\u091d\u0915\u0930 \u0915\u093f\u090f \u0917\u090f, \u091c\u0941\u0921\u093c\u093e\u0935-\u0906\u0927\u093e\u0930\u093f\u0924 \u090f\u0928\u094d\u0915\u094b\u0921\u093f\u0902\u0917 \u0914\u0930 \u0915\u094d\u0930\u092e\u092c\u0926\u094d\u0927 \u0938\u094d\u092e\u0930\u0923 \u0915\u094b \u0938\u093e\u0927\u0924\u093e \u0939\u0948: \u0915\u093f\u0938\u0940 \u0915\u094d\u0930\u092e \u0915\u094b \u0925\u093e\u092e\u0947 \u0930\u0916\u0928\u0947, \u0905\u0928\u094d\u092f\u0925\u093e \u0928\u093f\u0930\u0930\u094d\u0925\u0915 \u091a\u0940\u091c\u093c\u094b\u0902 \u0915\u094b \u0905\u0930\u094d\u0925 \u0926\u0947\u0928\u0947, \u0914\u0930 \u0909\u0928\u094d\u0939\u0947\u0902 \u0938\u0939\u0940 \u0915\u094d\u0930\u092e \u092e\u0947\u0902 \u0926\u094b\u092c\u093e\u0930\u093e \u092c\u0924\u093e\u0928\u0947 \u0915\u0940 \u0906\u092a\u0915\u0940 \u0915\u094d\u0937\u092e\u0924\u093e\u0964 \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0947 \u0938\u093e\u0925 \u092f\u0939 \u0905\u092e\u0942\u0930\u094d\u0924 \u0938\u093e\u092e\u0917\u094d\u0930\u0940 \u0915\u094b \u0920\u094b\u0938 \u091a\u093f\u0924\u094d\u0930\u094b\u0902 \u092e\u0947\u0902 \u092c\u0926\u0932\u0928\u0947 \u0915\u0940 \u0906\u0926\u0924 \u092d\u0940 \u092a\u0915\u094d\u0915\u0940 \u0915\u0930\u0924\u093e \u0939\u0948\u0964",history:"\u0907\u0938\u0915\u0947 \u092a\u0940\u091b\u0947 \u0915\u093e \u0935\u093f\u091a\u093e\u0930 \u092a\u0936\u094d\u091a\u093f\u092e\u0940 \u092a\u0930\u0902\u092a\u0930\u093e \u0915\u0940 \u0938\u092c\u0938\u0947 \u092a\u0941\u0930\u093e\u0928\u0940 \u092a\u094d\u0930\u0932\u0947\u0916\u093f\u0924 \u0938\u094d\u092e\u0943\u0924\u093f-\u0938\u0939\u093e\u092f\u0924\u093e\u0913\u0902 \u092e\u0947\u0902 \u0938\u0947 \u090f\u0915 \u0939\u0948 \u2014 \"\u0938\u094d\u092e\u0943\u0924\u093f-\u0915\u0932\u093e\" (\u0906\u0930\u094d\u091f \u0911\u092b\u093c \u092e\u0947\u092e\u094b\u0930\u0940)\u0964 \u092f\u0942\u0928\u093e\u0928\u0940 \u0914\u0930 \u0930\u094b\u092e\u0928 \u0935\u0915\u094d\u0924\u093e\u0913\u0902 \u0928\u0947 \u0932\u0902\u092c\u0947 \u092d\u093e\u0937\u0923 \u092f\u093e\u0926 \u0915\u0930\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0907\u0938\u0947 \u0938\u0930\u093e\u0939\u093e, \u092f\u0939 \u092e\u0927\u094d\u092f\u0915\u093e\u0932\u0940\u0928 \u0914\u0930 \u092a\u0941\u0928\u0930\u094d\u091c\u093e\u0917\u0930\u0923 \u0915\u0947 \u0917\u094d\u0930\u0902\u0925\u094b\u0902 \u0938\u0947 \u0939\u094b\u0915\u0930 \u0917\u0941\u091c\u093c\u0930\u0940, \u0914\u0930 \u0906\u091c \u092a\u094d\u0930\u0924\u093f\u0938\u094d\u092a\u0930\u094d\u0927\u0940 \u0938\u094d\u092e\u0943\u0924\u093f-\u0916\u0947\u0932\u094b\u0902 \u092e\u0947\u0902 \u091c\u0940\u0935\u093f\u0924 \u0939\u0948, \u091c\u0939\u093e\u0901 \u0916\u093f\u0932\u093e\u0921\u093c\u0940 \u0924\u093e\u0936 \u0915\u0940 \u0917\u0921\u094d\u0921\u093f\u092f\u093e\u0901 \u0914\u0930 \u0905\u0902\u0915\u094b\u0902 \u0915\u0940 \u0932\u0902\u092c\u0940 \u0932\u0921\u093c\u093f\u092f\u093e\u0901 \u092f\u093e\u0926 \u0915\u0930\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0907\u0938\u0915\u093e \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902\u0964",creator:"\u0907\u0938\u0915\u093e \u0915\u094b\u0908 \u090f\u0915 \u0906\u0935\u093f\u0937\u094d\u0915\u093e\u0930\u0915 \u0928\u0939\u0940\u0902 \u0939\u0948\u0964 \u092f\u0939 \u0924\u0915\u0928\u0940\u0915 \u092a\u0930\u0902\u092a\u0930\u093e\u0917\u0924 \u0930\u0942\u092a \u0938\u0947 \u0932\u0917\u092d\u0917 500 \u0908\u0938\u093e \u092a\u0942\u0930\u094d\u0935 \u0915\u0947 \u092f\u0942\u0928\u093e\u0928\u0940 \u0915\u0935\u093f \u0938\u093f\u092e\u094b\u0928\u093f\u0921\u0940\u091c\u093c \u0911\u092b\u093c \u0938\u0940\u0913\u0938 (Simonides of Ceos) \u0915\u094b \u0926\u0940 \u091c\u093e\u0924\u0940 \u0939\u0948, \u092a\u0930 \u0935\u0939 \u0915\u0939\u093e\u0928\u0940 \u0939\u092e \u0924\u0915 \u0915\u0947\u0935\u0932 \u0938\u093f\u0938\u0930\u094b (Cicero) \u0915\u0947 \u092c\u093e\u0926 \u0915\u0947 \u0935\u093f\u0935\u0930\u0923 De Oratore (55 \u0908\u0938\u093e \u092a\u0942\u0930\u094d\u0935) \u0915\u0947 \u091c\u093c\u0930\u093f\u090f \u092a\u0939\u0941\u0901\u091a\u0940 \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u092f\u0939 \u091c\u093f\u0924\u0928\u093e \u0907\u0924\u093f\u0939\u093e\u0938 \u0939\u0948 \u0909\u0924\u0928\u0940 \u0939\u0940 \u0915\u093f\u0902\u0935\u0926\u0902\u0924\u0940\u0964 \u092f\u0939\u093e\u0901 \u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0909\u0938\u0940 \u092a\u094d\u0930\u093e\u091a\u0940\u0928 \u092a\u0930\u0902\u092a\u0930\u093e \u092a\u0930 \u092c\u0928\u093e \u090f\u0915 \u0906\u0927\u0941\u0928\u093f\u0915 \u0921\u094d\u0930\u093f\u0932 \u0939\u0948, \u0915\u093f\u0938\u0940 \u090f\u0915 \u0935\u094d\u092f\u0915\u094d\u0924\u093f \u0915\u0940 \u0916\u094b\u091c \u0928\u0939\u0940\u0902\u0964",methods:"\u091a\u0940\u091c\u093c\u094b\u0902 \u0915\u094b \u090f\u0915 \u0938\u092a\u093e\u091f \u0938\u0942\u091a\u0940 \u0915\u0940 \u0924\u0930\u0939 \u0928 \u0926\u094b\u0939\u0930\u093e\u090f\u0901; \u0939\u0930 \u091a\u0940\u091c\u093c \u0915\u094b \u090f\u0915 \u092d\u0921\u093c\u0915\u0940\u0932\u0947, \u0925\u094b\u0921\u093c\u0947 \u092c\u0947\u0924\u0941\u0915\u0947 \u091a\u093f\u0924\u094d\u0930 \u092e\u0947\u0902 \u092c\u0926\u0932\u0947\u0902 \u0914\u0930 \u091a\u093f\u0924\u094d\u0930\u094b\u0902 \u0915\u094b \u090f\u0915 \u0936\u0943\u0902\u0916\u0932\u093e \u092e\u0947\u0902 \u092f\u093e \u0915\u093f\u0938\u0940 \u091c\u093e\u0928\u0940-\u092a\u0939\u091a\u093e\u0928\u0940 \u091c\u0917\u0939 \u0915\u0940 \u0938\u0948\u0930 \u092e\u0947\u0902 \u091c\u094b\u0921\u093c\u0947\u0902\u0964 \u091a\u0940\u091c\u093c \u0915\u094b \u0938\u092c\u0938\u0947 \u092a\u0939\u0932\u0947 \u0926\u0947\u0916\u0924\u0947 \u0939\u0940 \u0909\u0938\u0940 \u092a\u0932 \u090f\u0928\u094d\u0915\u094b\u0921 \u0915\u0930\u0947\u0902, \u0905\u0902\u0924 \u092e\u0947\u0902 \u0928\u0939\u0940\u0902; \u091a\u093f\u0924\u094d\u0930\u094b\u0902 \u0915\u094b \u092c\u0922\u093c\u093e-\u091a\u0922\u093c\u093e\u0915\u0930 \u0914\u0930 \u0909\u0928\u092e\u0947\u0902 \u0917\u0924\u093f \u0921\u093e\u0932\u0915\u0930 \u0909\u0928\u094d\u0939\u0947\u0902 \u091a\u093f\u092a\u0915\u0928\u0947 \u0932\u093e\u092f\u0915 \u092c\u0928\u093e\u090f\u0901; \u0914\u0930 \u0938\u094d\u092e\u0930\u0923 \u0915\u0947 \u0938\u092e\u092f \u091a\u0940\u091c\u093c\u094b\u0902 \u0915\u094b \u092f\u093e\u0926\u0943\u091a\u094d\u091b\u093f\u0915 \u0930\u0942\u092a \u0938\u0947 \u092a\u0915\u0921\u093c\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u0909\u0938\u0940 \u0930\u093e\u0938\u094d\u0924\u0947 \u092f\u093e \u0936\u0943\u0902\u0916\u0932\u093e \u0915\u094b \u0915\u094d\u0930\u092e \u092e\u0947\u0902 \u092b\u093f\u0930 \u0938\u0947 \u0924\u092f \u0915\u0930\u0947\u0902\u0964",duration:"\u091b\u094b\u091f\u093e \u0914\u0930 \u092c\u093e\u0930-\u092c\u093e\u0930 \u0939\u094b\u0928\u093e, \u0932\u0902\u092c\u0947 \u0914\u0930 \u0915\u092d\u0940-\u0915\u092d\u093e\u0930 \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u0939\u0948\u0964 \u0926\u0938 \u0938\u0947 \u092a\u0902\u0926\u094d\u0930\u0939 \u092e\u093f\u0928\u091f, \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u0915\u0941\u091b \u092c\u093e\u0930, \u090f\u0928\u094d\u0915\u094b\u0921\u093f\u0902\u0917 \u0915\u0940 \u0906\u0926\u0924 \u092c\u0928\u093e\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0915\u093e\u092b\u093c\u0940 \u0939\u0948\u0902; \u0915\u0941\u0932 \u0938\u092e\u092f \u0938\u0947 \u0915\u0939\u0940\u0902 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u091a\u093f\u0924\u094d\u0930\u094b\u0902 \u0915\u0940 \u0917\u0941\u0923\u0935\u0924\u094d\u0924\u093e \u092e\u093e\u092f\u0928\u0947 \u0930\u0916\u0924\u0940 \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u091c\u0948\u0938\u0947 \u0939\u0940 \u0906\u092a\u0915\u0947 \u091a\u093f\u0924\u094d\u0930 \u0922\u0940\u0932\u0947 \u092a\u0921\u093c\u0928\u0947 \u0932\u0917\u0947\u0902, \u0930\u0941\u0915 \u091c\u093e\u090f\u0901\u0964",research:"\u091c\u093f\u0938\u0915\u0940 \u0905\u092a\u0947\u0915\u094d\u0937\u093e \u0939\u0948, \u092a\u094d\u0930\u092e\u093e\u0923 \u0920\u0940\u0915 \u0909\u0938\u0940 \u0915\u0947 \u0932\u093f\u090f \u092e\u091c\u093c\u092c\u0942\u0924 \u0939\u0948\u0902 \u2014 \u0907\u0938 \u0924\u0930\u0939 \u0915\u0940 \u091a\u093f\u0924\u094d\u0930- \u0914\u0930 \u0930\u093e\u0938\u094d\u0924\u0947-\u0906\u0927\u093e\u0930\u093f\u0924 \u0935\u093f\u0927\u093f \u092e\u0947\u0902 \u0938\u0927\u0947 \u0932\u094b\u0917 \u0915\u094d\u0930\u092e\u092c\u0926\u094d\u0927 \u0938\u0942\u091a\u093f\u092f\u093e\u0901 \u0915\u0939\u0940\u0902 \u092c\u0947\u0939\u0924\u0930 \u092f\u093e\u0926 \u0930\u0916\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u090f\u0915 2017 \u0915\u0947 \u0905\u0927\u094d\u092f\u092f\u0928 (Dresler \u0914\u0930 \u0938\u0939\u092f\u094b\u0917\u0940) \u0928\u0947 \u0926\u093f\u0916\u093e\u092f\u093e \u0915\u093f \u091b\u0939 \u0939\u092b\u093c\u094d\u0924\u094b\u0902 \u0915\u0947 \u092e\u0947\u0925\u0921-\u0911\u092b\u093c-\u0932\u094b\u0938\u093e\u0908 \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u0928\u0947 \u0936\u0941\u0930\u0941\u0906\u0924\u0940 \u0932\u094b\u0917\u094b\u0902 \u092e\u0947\u0902 \u0938\u094d\u092e\u0930\u0923 \u0932\u0917\u092d\u0917 \u0926\u094b\u0917\u0941\u0928\u093e \u0915\u0930 \u0926\u093f\u092f\u093e \u0914\u0930 \u0909\u0928\u0915\u0940 \u092e\u0938\u094d\u0924\u093f\u0937\u094d\u0915-\u0938\u0902\u092f\u094b\u091c\u0915\u0924\u093e \u0915\u094b \u0936\u0940\u0930\u094d\u0937 \u0938\u094d\u092e\u0943\u0924\u093f-\u0916\u093f\u0932\u093e\u0921\u093c\u093f\u092f\u094b\u0902 \u091c\u0948\u0938\u0940 \u0913\u0930 \u0916\u093f\u0938\u0915\u093e \u0926\u093f\u092f\u093e\u0964 \u0915\u092e\u091c\u093c\u094b\u0930 \u0926\u093e\u0935\u0947 \u0935\u094d\u092f\u093e\u092a\u0915 \u0935\u093e\u0932\u0947 \u0939\u0948\u0902: \u0938\u094d\u092e\u0943\u0924\u093f-\u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u0915\u0947 \u092c\u0921\u093c\u0947 \u092e\u0947\u091f\u093e-\u0935\u093f\u0936\u094d\u0932\u0947\u0937\u0923 \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u092c\u0941\u0926\u094d\u0927\u093f \u092f\u093e \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0940 \u0938\u094b\u091a \u0924\u0915 \u092c\u0939\u0941\u0924 \u0915\u092e \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \"\u0926\u0942\u0930-\u0939\u0938\u094d\u0924\u093e\u0902\u0924\u0930\u0923\" \u092a\u093e\u0924\u0947 \u0939\u0948\u0902, \u0907\u0938\u0932\u093f\u090f \u090a\u0901\u091a\u0947 IQ \u092f\u093e \u0939\u0930 \u0924\u0930\u092b\u093c \u0924\u0947\u091c\u093c \u0926\u093f\u092e\u093e\u0917\u093c \u0915\u0947 \u0935\u093e\u0926\u094b\u0902 \u0915\u094b \u0938\u093e\u0935\u0927\u093e\u0928\u0940 \u0938\u0947 \u0932\u0947\u0902\u0964 \u0906\u092a\u0915\u094b \u092e\u0941\u0916\u094d\u092f\u0924\u0903 \u091c\u094b \u092e\u093f\u0932\u0924\u093e \u0939\u0948 \u0935\u0939 \u0909\u0938 \u0938\u093e\u092e\u0917\u094d\u0930\u0940 \u0915\u094b \u092f\u093e\u0926 \u0915\u0930\u0928\u0947 \u0915\u093e \u090f\u0915 \u0924\u093e\u0915\u093c\u0924\u0935\u0930, \u0938\u0940\u0916\u0928\u0947-\u092f\u094b\u0917\u094d\u092f \u0939\u0941\u0928\u0930 \u0939\u0948 \u091c\u093f\u0938\u0947 \u090f\u0928\u094d\u0915\u094b\u0921 \u0915\u0930\u0928\u093e \u0906\u092a \u0916\u093c\u0941\u0926 \u091a\u0941\u0928\u0924\u0947 \u0939\u0948\u0902\u0964",rec:"\u090f\u0915 \u091c\u093e\u0928\u0940-\u092a\u0939\u091a\u093e\u0928\u0940 \u091c\u0917\u0939 \u091a\u0941\u0928\u0947\u0902 \u2014 \u0905\u092a\u0928\u093e \u0918\u0930, \u0905\u092a\u0928\u093e \u0930\u094b\u091c\u093c \u0915\u093e \u0930\u093e\u0938\u094d\u0924\u093e \u2014 \u0914\u0930 \u0939\u0930 \u0938\u0924\u094d\u0930 \u092e\u0947\u0902 \u0909\u0938\u0940 \u0915\u093e \u0926\u094b\u092c\u093e\u0930\u093e \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0915\u0930\u0947\u0902; \u090f\u0915 \u0938\u094d\u0925\u093f\u0930, \u0905\u091a\u094d\u091b\u0940 \u0924\u0930\u0939 \u0918\u093f\u0938\u093e-\u092a\u093f\u091f\u093e \u0930\u093e\u0938\u094d\u0924\u093e \u0939\u0930 \u092c\u093e\u0930 \u0915\u0947 \u0928\u090f-\u0928\u0935\u0947\u0932\u0947 \u0930\u093e\u0938\u094d\u0924\u0947 \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u0938\u094d\u092e\u0943\u0924\u093f-\u0938\u0939\u093e\u092f\u0924\u093e \u0939\u0948\u0964",faq:[["\u0915\u094d\u092f\u093e \u0907\u0938\u0938\u0947 \u092e\u0947\u0930\u0940 \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0940 \u0938\u094d\u092e\u0943\u0924\u093f \u092c\u0947\u0939\u0924\u0930 \u0939\u094b\u0917\u0940?","\u092f\u0939 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0930\u0942\u092a \u0938\u0947 \u0906\u092a\u0915\u094b \u0909\u0928 \u091a\u0940\u091c\u093c\u094b\u0902 \u0915\u094b \u092f\u093e\u0926 \u0915\u0930\u0928\u0947 \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u092c\u0928\u093e\u0924\u093e \u0939\u0948 \u091c\u093f\u0928\u094d\u0939\u0947\u0902 \u0906\u092a \u091c\u093e\u0928-\u092c\u0942\u091d\u0915\u0930 \u0907\u0938 \u0924\u0915\u0928\u0940\u0915 \u0938\u0947 \u090f\u0928\u094d\u0915\u094b\u0921 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902, \u091c\u0948\u0938\u0947 \u0938\u0942\u091a\u093f\u092f\u093e\u0901, \u0928\u093e\u092e \u092f\u093e \u092d\u093e\u0937\u0923\u0964 \u092f\u0939 \u0915\u0939\u0940\u0902 \u0915\u092e \u092a\u094d\u0930\u092e\u093e\u0923\u093f\u0924 \u0939\u0948 \u0915\u093f \u092f\u0939 \u0939\u0930 \u0924\u0930\u092b\u093c \u0915\u0940 \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u0938\u094d\u092e\u0943\u0924\u093f \u092f\u093e \u092c\u0941\u0926\u094d\u0927\u093f \u0915\u094b \u0924\u0947\u091c\u093c \u0915\u0930\u0924\u093e \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0907\u0938\u0947 \u090f\u0915 \u0914\u091c\u093c\u093e\u0930 \u0938\u092e\u091d\u0947\u0902 \u091c\u093f\u0938\u0947 \u0906\u092a \u0932\u0917\u093e\u0924\u0947 \u0939\u0948\u0902, \u0915\u094b\u0908 \u0926\u093f\u092e\u093e\u0917\u093c\u0940 \u0905\u092a\u0917\u094d\u0930\u0947\u0921 \u0928\u0939\u0940\u0902\u0964"],["\u092e\u0948\u0902 \u091a\u0940\u091c\u093c\u094b\u0902 \u0915\u0940 \u0915\u0932\u094d\u092a\u0928\u093e \u0915\u0930\u0928\u0947 \u092e\u0947\u0902 \u0915\u092e\u091c\u093c\u094b\u0930 \u0939\u0942\u0901 \u2014 \u0915\u094d\u092f\u093e \u092b\u093f\u0930 \u092d\u0940 \u0915\u0930 \u0938\u0915\u0924\u093e \u0939\u0942\u0901?","\u0939\u093e\u0901\u0964 \u091c\u0940\u0935\u0902\u0924\u0924\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0947 \u0938\u093e\u0925 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b\u0924\u0940 \u0939\u0948, \u0914\u0930 \u0906\u092a \u0926\u0942\u0938\u0930\u0940 \u0907\u0902\u0926\u094d\u0930\u093f\u092f\u094b\u0902 \u092a\u0930, \u091a\u0940\u091c\u093c\u094b\u0902 \u0915\u094b \u091c\u094b\u0921\u093c\u0928\u0947 \u0935\u093e\u0932\u0940 \u0915\u093f\u0938\u0940 \u0915\u0939\u093e\u0928\u0940 \u092a\u0930, \u092f\u093e \u0915\u093f\u0938\u0940 \u091c\u093e\u0928\u0947-\u092a\u0939\u091a\u093e\u0928\u0947 \u0930\u093e\u0938\u094d\u0924\u0947 \u092a\u0930 \u091f\u093f\u0915 \u0938\u0915\u0924\u0947 \u0939\u0948\u0902\u0964 \u091a\u093f\u0924\u094d\u0930\u094b\u0902 \u0915\u094b \u092c\u0938 \u0906\u092a\u0915\u0947 \u0932\u093f\u090f \u0915\u094b\u0908 \u092e\u0924\u0932\u092c \u0930\u0916\u0928\u093e \u0939\u0948; \u0909\u0928\u094d\u0939\u0947\u0902 \u092b\u093c\u093f\u0932\u094d\u092e\u0940 \u0939\u094b\u0928\u0947 \u0915\u0940 \u091c\u093c\u0930\u0942\u0930\u0924 \u0928\u0939\u0940\u0902\u0964"],["\u091c\u092c \u092e\u0948\u0902 \u0938\u0942\u091a\u0940 \u0932\u093f\u0916 \u0939\u0940 \u0938\u0915\u0924\u093e \u0939\u0942\u0901 \u0924\u094b \u0907\u0924\u0928\u0940 \u092e\u0947\u0939\u0928\u0924 \u0915\u094d\u092f\u094b\u0902?","\u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0947 \u0915\u093e\u092e\u094b\u0902 \u0915\u0947 \u0932\u093f\u090f \u0932\u093f\u0916 \u0932\u0947\u0928\u093e \u0906\u092e\u0924\u094c\u0930 \u092a\u0930 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0938\u092e\u091d\u0926\u093e\u0930\u0940 \u0939\u0948\u0964 \u092f\u0939 \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u094d\u0930\u092e\u092c\u0926\u094d\u0927, \u091c\u0941\u0921\u093c\u093e\u0935-\u0906\u0927\u093e\u0930\u093f\u0924 \u0938\u094d\u092e\u0930\u0923 \u0915\u0947 \u0905\u0902\u0924\u0930\u094d\u0928\u093f\u0939\u093f\u0924 \u0939\u0941\u0928\u0930 \u0915\u094b \u0938\u093e\u0927\u0924\u093e \u0939\u0948, \u091c\u094b \u0924\u092c \u0915\u093e\u092e \u0906\u0924\u093e \u0939\u0948 \u091c\u092c \u0906\u092a \u0928\u094b\u091f \u0928\u0939\u0940\u0902 \u0932\u0947 \u0938\u0915\u0924\u0947, \u0924\u0947\u091c\u093c \u092f\u093e\u0926-\u0926\u093f\u0932\u093e\u0935 \u091a\u093e\u0939\u0924\u0947 \u0939\u0948\u0902, \u092f\u093e \u092c\u0938 \u090f\u0915 \u092e\u091c\u093c\u092c\u0942\u0924, \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0932\u091a\u0940\u0932\u0940 \u0938\u094d\u092e\u0943\u0924\u093f \u091a\u093e\u0939\u0924\u0947 \u0939\u0948\u0902\u0964"]],variants:"\u0935\u093f\u0935\u093f\u0927\u0924\u093e\u0913\u0902 \u092e\u0947\u0902 \u092e\u0947\u0925\u0921 \u0911\u092b\u093c \u0932\u094b\u0938\u093e\u0908 (\u091a\u0940\u091c\u093c\u094b\u0902 \u0915\u094b \u092f\u093e\u0926 \u0915\u093f\u090f \u0939\u0941\u090f \u0930\u093e\u0938\u094d\u0924\u0947 \u092a\u0930 \u0930\u0916\u0928\u093e), \u0932\u093f\u0902\u0915\u093f\u0902\u0917 \u092f\u093e \u0938\u094d\u091f\u094b\u0930\u0940 \u0935\u093f\u0927\u093f (\u0939\u0930 \u091a\u0940\u091c\u093c \u0915\u094b \u0905\u0917\u0932\u0940 \u0938\u0947 \u090f\u0915 \u0915\u0939\u093e\u0928\u0940 \u092e\u0947\u0902 \u092c\u093e\u0901\u0927\u0928\u093e), \u092a\u0947\u0917 \u0938\u093f\u0938\u094d\u091f\u092e (\u091a\u0940\u091c\u093c\u094b\u0902 \u0915\u094b \u090f\u0915 \u0924\u092f \u0915\u094d\u0930\u092e\u093e\u0902\u0915\u093f\u0924 \u0938\u0942\u091a\u0940 \u092a\u0930 \u091f\u093e\u0901\u0917\u0928\u093e), \u0914\u0930 \u0915\u0920\u093f\u0928 \u092e\u094b\u0921 \u0936\u093e\u092e\u093f\u0932 \u0939\u0948\u0902 \u091c\u094b \u0915\u094d\u0930\u092e \u0915\u094b \u0932\u0902\u092c\u093e \u0915\u0930 \u0926\u0947\u0924\u0947 \u0939\u0948\u0902, \u0926\u0947\u0916\u0928\u0947 \u0915\u093e \u0938\u092e\u092f \u0918\u091f\u093e \u0926\u0947\u0924\u0947 \u0939\u0948\u0902, \u092f\u093e \u0909\u0938\u092e\u0947\u0902 \u0905\u092e\u0942\u0930\u094d\u0924 \u091a\u093f\u0939\u094d\u0928 \u0914\u0930 \u0905\u0902\u0915 \u092e\u093f\u0932\u093e \u0926\u0947\u0924\u0947 \u0939\u0948\u0902\u0964"},zh:{about:"\u300a\u8bb0\u5fc6\u672f\uff1a\u5e8f\u5217\u300b\u4f1a\u7ed9\u4f60\u770b\u4e00\u4efd\u7b80\u77ed\u7684\u6709\u5e8f\u6761\u76ee\u6e05\u5355\uff0c\u7136\u540e\u8981\u6c42\u4f60\u4ee5\u5b8c\u5168\u76f8\u540c\u7684\u987a\u5e8f\u590d\u73b0\u5b83\u4eec\u3002\u91cd\u70b9\u4e0d\u5728\u4e8e\u76ef\u7740\u770b\u3001\u53cd\u590d\u5ff5\uff0c\u800c\u5728\u4e8e\u7528\u4e00\u5e45\u751f\u52a8\u7684\u5fc3\u7406\u56fe\u50cf\u3001\u6216\u4e00\u6761\u7a7f\u8fc7\u719f\u6089\u573a\u6240\u7684\u8def\u7ebf\uff0c\u628a\u6bcf\u4e2a\u6761\u76ee\u4e0e\u4e0b\u4e00\u4e2a\u8054\u7cfb\u8d77\u6765\uff0c\u8ba9\u987a\u5e8f\u7531\u8054\u60f3\u6765\u627f\u8f7d\uff0c\u800c\u975e\u9760\u751f\u529b\u6c14\u3002",benefit:"\u5b83\u8bad\u7ec3\u523b\u610f\u7684\u8054\u60f3\u7f16\u7801\u548c\u6709\u5e8f\u56de\u5fc6\uff1a\u5373\u4f60\u4fdd\u6301\u4e00\u4e2a\u5e8f\u5217\u3001\u4e3a\u672c\u65e0\u610f\u4e49\u7684\u6761\u76ee\u8d4b\u4e88\u610f\u4e49\u3001\u5e76\u6309\u6b63\u786e\u987a\u5e8f\u64ad\u653e\u51fa\u6765\u7684\u80fd\u529b\u3002\u7ecf\u8fc7\u7ec3\u4e60\uff0c\u5b83\u8fd8\u80fd\u517b\u6210\u628a\u62bd\u8c61\u6750\u6599\u8f6c\u5316\u4e3a\u5177\u4f53\u56fe\u50cf\u7684\u4e60\u60ef\u3002",history:"\u5176\u5e95\u5c42\u7406\u5ff5\u662f\u897f\u65b9\u4f20\u7edf\u4e2d\u6709\u6587\u732e\u8bb0\u8f7d\u7684\u6700\u53e4\u8001\u7684\u8bb0\u5fc6\u672f\u4e4b\u4e00\u2014\u2014\u201c\u8bb0\u5fc6\u7684\u827a\u672f\u201d\u3002\u5b83\u66fe\u88ab\u5e0c\u814a\u548c\u7f57\u9a6c\u7684\u6f14\u8bf4\u5bb6\u5949\u4e3a\u8bb0\u8bf5\u957f\u7bc7\u6f14\u8bb2\u7684\u6cd5\u5b9d\uff0c\u7ecf\u7531\u4e2d\u4e16\u7eaa\u548c\u6587\u827a\u590d\u5174\u65f6\u671f\u7684\u8bba\u8457\u6d41\u4f20\u4e0b\u6765\uff0c\u81f3\u4eca\u4ecd\u5b58\u6d3b\u4e8e\u7ade\u6280\u8bb0\u5fc6\u8fd0\u52a8\u4e2d\uff0c\u9009\u624b\u4eec\u7528\u5b83\u6765\u8bb0\u5fc6\u6574\u526f\u6251\u514b\u724c\u548c\u957f\u4e32\u6570\u5b57\u3002",creator:"\u5b83\u6ca1\u6709\u5355\u4e00\u7684\u53d1\u660e\u8005\u3002\u8fd9\u4e00\u6280\u672f\u4f20\u7edf\u4e0a\u5f52\u4e8e\u516c\u5143\u524d 500 \u5e74\u5de6\u53f3\u7684\u5e0c\u814a\u8bd7\u4eba\u51ef\u5965\u65af\u7684\u897f\u6469\u5c3c\u5f97\u65af\uff08Simonides of Ceos\uff09\uff0c\u4f46\u8fd9\u4e2a\u6545\u4e8b\u53ea\u901a\u8fc7\u897f\u585e\u7f57\u540e\u6765\u5728\u300a\u8bba\u6f14\u8bf4\u5bb6\u300b\uff08De Oratore\uff0c\u516c\u5143\u524d 55 \u5e74\uff09\u4e2d\u7684\u8bb0\u8ff0\u4f20\u5230\u6211\u4eec\u624b\u4e2d\uff0c\u6240\u4ee5\u5b83\u4e0e\u5176\u8bf4\u662f\u53f2\u5b9e\uff0c\u4e0d\u5982\u8bf4\u662f\u4f20\u8bf4\u3002\u8fd9\u91cc\u7684\u7ec3\u4e60\u662f\u5efa\u7acb\u5728\u90a3\u4e00\u53e4\u8001\u4f20\u7edf\u4e4b\u4e0a\u7684\u73b0\u4ee3\u8bad\u7ec3\uff0c\u800c\u975e\u4efb\u4f55\u4e00\u4e2a\u4eba\u7684\u53d1\u660e\u3002",methods:"\u4e0d\u8981\u628a\u6761\u76ee\u5f53\u4f5c\u4e00\u4efd\u6241\u5e73\u7684\u6e05\u5355\u53bb\u6f14\u7ec3\uff1b\u628a\u6bcf\u4e00\u4e2a\u90fd\u53d8\u6210\u4e00\u5e45\u9192\u76ee\u3001\u7565\u5e26\u8352\u8bde\u7684\u56fe\u50cf\uff0c\u518d\u628a\u8fd9\u4e9b\u56fe\u50cf\u4e32\u6210\u4e00\u6761\u94fe\uff0c\u6216\u4e00\u6bb5\u7a7f\u8fc7\u4f60\u719f\u6089\u4e4b\u5730\u7684\u6563\u6b65\u3002\u5728\u4f60\u521d\u6b21\u770b\u5230\u67d0\u4e2a\u6761\u76ee\u7684\u5f53\u4e0b\u5c31\u7f16\u7801\uff0c\u800c\u4e0d\u662f\u7b49\u5230\u6700\u540e\uff1b\u5938\u5f20\u5e76\u52a0\u5165\u52a8\u4f5c\uff0c\u8ba9\u56fe\u50cf\u66f4\u7262\u56fa\uff1b\u56de\u5fc6\u65f6\uff0c\u6cbf\u7740\u540c\u4e00\u6761\u8def\u7ebf\u6216\u94fe\u6761\u6309\u987a\u5e8f\u91cd\u8d70\uff0c\u800c\u4e0d\u662f\u968f\u610f\u6293\u53d6\u6761\u76ee\u3002",duration:"\u77ed\u800c\u9891\u7e41\u80dc\u8fc7\u5197\u957f\u800c\u7a00\u5c11\u3002\u6bcf\u5468\u51e0\u6b21\u3001\u6bcf\u6b21\u5341\u5230\u5341\u4e94\u5206\u949f\uff0c\u5c31\u8db3\u4ee5\u517b\u6210\u7f16\u7801\u4e60\u60ef\uff1b\u56fe\u50cf\u7684\u8d28\u91cf\u8fdc\u6bd4\u603b\u65f6\u957f\u66f4\u91cd\u8981\uff0c\u6240\u4ee5\u4e00\u65e6\u4f60\u7684\u56fe\u50cf\u5f00\u59cb\u5077\u61d2\uff0c\u5c31\u505c\u4e0b\u6765\u3002",research:"\u8bc1\u636e\u6700\u5145\u5206\u7684\u6070\u6070\u662f\u4f60\u80fd\u9884\u6599\u5230\u7684\u90e8\u5206\u2014\u2014\u63a5\u53d7\u8fc7\u8fd9\u7c7b\u56fe\u50cf\u4e0e\u8def\u7ebf\u65b9\u6cd5\u8bad\u7ec3\u7684\u4eba\uff0c\u5bf9\u6709\u5e8f\u6e05\u5355\u7684\u56de\u5fc6\u8981\u597d\u5f97\u591a\uff1b\u4e00\u9879 2017 \u5e74\u7684\u7814\u7a76\uff08Dresler \u53ca\u5176\u540c\u4e8b\uff09\u663e\u793a\uff0c\u516d\u5468\u7684\u4f4d\u7f6e\u8bb0\u5fc6\u6cd5\u8bad\u7ec3\u8ba9\u521d\u5b66\u8005\u7684\u56de\u5fc6\u91cf\u5927\u7ea6\u7ffb\u500d\uff0c\u5e76\u4f7f\u4ed6\u4eec\u7684\u8111\u8fde\u63a5\u6a21\u5f0f\u5411\u9876\u5c16\u8bb0\u5fc6\u8fd0\u52a8\u5458\u9760\u62e2\u3002\u8f83\u8584\u5f31\u7684\u662f\u90a3\u4e9b\u5bbd\u6cdb\u7684\u8bf4\u6cd5\uff1a\u8bb0\u5fc6\u8bad\u7ec3\u7684\u5927\u578b\u5143\u5206\u6790\u51e0\u4e4e\u627e\u4e0d\u5230\u53ef\u9760\u7684\u201c\u8fdc\u8fc1\u79fb\u201d\u3001\u80fd\u6ce2\u53ca\u6574\u4f53\u667a\u529b\u6216\u65e5\u5e38\u8ba4\u77e5\uff0c\u6240\u4ee5\u5bf9\u201c\u63d0\u5347\u667a\u5546\u6216\u5168\u9762\u53d8\u806a\u660e\u201d\u7684\u627f\u8bfa\u8981\u4fdd\u6301\u8c28\u614e\u3002\u4f60\u4e3b\u8981\u5f97\u5230\u7684\uff0c\u662f\u4e00\u9879\u5f3a\u5927\u3001\u53ef\u4e60\u5f97\u7684\u6280\u80fd\uff0c\u7528\u6765\u8bb0\u5fc6\u4f60\u9009\u62e9\u53bb\u7f16\u7801\u7684\u6750\u6599\u3002",rec:"\u9009\u5b9a\u4e00\u6761\u719f\u6089\u7684\u8def\u7ebf\u2014\u2014\u4f60\u7684\u5bb6\u3001\u4f60\u7684\u901a\u52e4\u8def\u2014\u2014\u5e76\u5728\u6bcf\u4e00\u6b21\u7ec3\u4e60\u4e2d\u91cd\u590d\u4f7f\u7528\u5b83\uff1b\u4e00\u6761\u7a33\u5b9a\u3001\u8d70\u719f\u4e86\u7684\u8def\uff0c\u6bd4\u6bcf\u6b21\u90fd\u6362\u4e00\u6761\u82b1\u54e8\u7684\u65b0\u8def\u66f4\u80fd\u52a9\u8bb0\u3002",faq:[["\u8fd9\u4f1a\u8ba9\u6211\u65e5\u5e38\u7684\u8bb0\u5fc6\u53d8\u597d\u5417\uff1f","\u5b83\u80fd\u53ef\u9760\u5730\u63d0\u5347\u4f60\u8bb0\u5fc6\u90a3\u4e9b\u4f60\u523b\u610f\u7528\u8be5\u6280\u672f\u7f16\u7801\u4e4b\u7269\u7684\u672c\u9886\uff0c\u6bd4\u5982\u6e05\u5355\u3001\u540d\u5b57\u6216\u6f14\u8bb2\u7a3f\u3002\u81f3\u4e8e\u5b83\u80fd\u5426\u5168\u9762\u78e8\u783a\u6574\u4f53\u8bb0\u5fc6\u6216\u667a\u529b\uff0c\u5219\u8fdc\u672a\u5f97\u5230\u8bc1\u5b9e\uff0c\u6240\u4ee5\u8bf7\u628a\u5b83\u5f53\u4f5c\u4e00\u4ef6\u4f60\u62ff\u6765\u7528\u7684\u5de5\u5177\uff0c\u800c\u975e\u4e00\u6b21\u5927\u8111\u5347\u7ea7\u3002"],["\u6211\u4e0d\u64c5\u957f\u5728\u8111\u4e2d\u60f3\u8c61\u753b\u9762\u2014\u2014\u8fd8\u80fd\u7528\u5b83\u5417\uff1f","\u80fd\u3002\u751f\u52a8\u5ea6\u4f1a\u968f\u7ec3\u4e60\u800c\u63d0\u5347\uff0c\u4f60\u4e5f\u53ef\u4ee5\u501f\u52a9\u5176\u4ed6\u611f\u5b98\u3001\u501f\u52a9\u4e00\u4e2a\u628a\u6761\u76ee\u8054\u7cfb\u8d77\u6765\u7684\u6545\u4e8b\uff0c\u6216\u501f\u52a9\u4e00\u6761\u719f\u6089\u7684\u8def\u7ebf\u3002\u56fe\u50cf\u53ea\u9700\u5bf9\u4f60\u6709\u610f\u4e49\u5373\u53ef\uff0c\u5e76\u4e0d\u5fc5\u62cd\u6210\u7535\u5f71\u3002"],["\u6211\u76f4\u63a5\u5199\u5f20\u6e05\u5355\u4e0d\u5c31\u884c\u4e86\uff0c\u4f55\u5fc5\u8d39\u8fd9\u4e2a\u52b2\uff1f","\u5bf9\u65e5\u5e38\u4e8b\u52a1\u6765\u8bf4\uff0c\u5199\u4e0b\u6765\u901a\u5e38\u66f4\u660e\u667a\u3002\u8fd9\u9879\u7ec3\u4e60\u8bad\u7ec3\u7684\u662f\u6709\u5e8f\u3001\u8054\u60f3\u5f0f\u56de\u5fc6\u8fd9\u4e00\u5e95\u5c42\u6280\u80fd\uff0c\u5f53\u4f60\u65e0\u6cd5\u8bb0\u7b14\u8bb0\u3001\u60f3\u66f4\u5feb\u63d0\u53d6\uff0c\u6216\u5355\u7eaf\u60f3\u8981\u4e00\u526f\u66f4\u5f3a\u3001\u66f4\u7075\u6d3b\u7684\u8bb0\u5fc6\u529b\u65f6\uff0c\u5b83\u5c31\u6d3e\u5f97\u4e0a\u7528\u573a\u3002"]],variants:"\u5404\u79cd\u53d8\u4f53\u5305\u62ec\u4f4d\u7f6e\u8bb0\u5fc6\u6cd5\uff08\u628a\u6761\u76ee\u6446\u653e\u5728\u4e00\u6761\u8bb0\u719f\u7684\u8def\u7ebf\u4e0a\uff09\u3001\u4e32\u8054\u6cd5\u6216\u6545\u4e8b\u6cd5\uff08\u7528\u53d9\u4e8b\u628a\u6bcf\u4e2a\u6761\u76ee\u63a5\u5230\u4e0b\u4e00\u4e2a\uff09\u3001\u6302\u94a9\u7cfb\u7edf\uff08\u628a\u6761\u76ee\u94a9\u5728\u4e00\u4efd\u56fa\u5b9a\u7f16\u53f7\u7684\u6e05\u5355\u4e0a\uff09\uff0c\u4ee5\u53ca\u66f4\u96be\u7684\u6a21\u5f0f\u2014\u2014\u52a0\u957f\u5e8f\u5217\u3001\u7f29\u77ed\u89c2\u770b\u65f6\u95f4\uff0c\u6216\u63ba\u5165\u62bd\u8c61\u7b26\u53f7\u548c\u6570\u5b57\u3002"}},"n-back":{ru:{about:"\u0421\u0442\u0438\u043c\u0443\u043b\u044b \u043f\u043e\u044f\u0432\u043b\u044f\u044e\u0442\u0441\u044f \u043f\u043e \u043e\u0434\u043d\u043e\u043c\u0443; \u0440\u0435\u0430\u0433\u0438\u0440\u0443\u0439, \u043a\u043e\u0433\u0434\u0430 \u0442\u0435\u043a\u0443\u0449\u0438\u0439 \u0441\u043e\u0432\u043f\u0430\u0434\u0430\u0435\u0442 \u0441 \u0442\u0435\u043c, \u0447\u0442\u043e \u0431\u044b\u043b N \u0448\u0430\u0433\u043e\u0432 \u043d\u0430\u0437\u0430\u0434. \u0421 \u0440\u043e\u0441\u0442\u043e\u043c N \u043e\u0442 1 \u043a 2 \u0438 3 \u043d\u0430\u0433\u0440\u0443\u0437\u043a\u0430 \u043d\u0430 \u0440\u0430\u0431\u043e\u0447\u0443\u044e \u043f\u0430\u043c\u044f\u0442\u044c \u0440\u0435\u0437\u043a\u043e \u0440\u0430\u0441\u0442\u0451\u0442.",benefit:"\u041e\u0431\u044a\u0451\u043c \u0440\u0430\u0431\u043e\u0447\u0435\u0439 \u043f\u0430\u043c\u044f\u0442\u0438, \u043e\u0431\u043d\u043e\u0432\u043b\u0435\u043d\u0438\u0435 (\u043f\u043e\u0441\u0442\u043e\u044f\u043d\u043d\u0430\u044f \u0437\u0430\u043c\u0435\u043d\u0430 \u0441\u0442\u0430\u0440\u044b\u0445 \u044d\u043b\u0435\u043c\u0435\u043d\u0442\u043e\u0432 \u043d\u043e\u0432\u044b\u043c\u0438) \u0438 \u0443\u0441\u0442\u043e\u0439\u0447\u0438\u0432\u043e\u0441\u0442\u044c \u043a \u043f\u043e\u043c\u0435\u0445\u0430\u043c \u2014 \u0442\u043e \u0441\u0430\u043c\u043e\u0435 \xab\u0443\u043c\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0435 \u0436\u043e\u043d\u0433\u043b\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u0435\xbb \u0437\u0430 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435\u043c \u0438 \u0440\u0430\u0441\u0441\u0443\u0436\u0434\u0435\u043d\u0438\u0435\u043c.",history:"\u041f\u0440\u043e\u0446\u0435\u0434\u0443\u0440\u0443 n-back \u0432\u0432\u0435\u043b\u0438 \u0432 1958-\u043c \u043a\u0430\u043a \u043b\u0430\u0431\u043e\u0440\u0430\u0442\u043e\u0440\u043d\u0443\u044e \u043c\u0435\u0440\u0443 \u0440\u0430\u0431\u043e\u0447\u0435\u0439 \u043f\u0430\u043c\u044f\u0442\u0438. \u0418\u0437\u0432\u0435\u0441\u0442\u043d\u043e\u0439 \u043e\u043d\u0430 \u0441\u0442\u0430\u043b\u0430 \u0432 2008-\u043c, \u043a\u043e\u0433\u0434\u0430 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u0435 \u0437\u0430\u044f\u0432\u0438\u043b\u043e, \u0447\u0442\u043e \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0430 \u0443\u0441\u043b\u043e\u0436\u043d\u0451\u043d\u043d\u043e\u0439 \xab\u0434\u0432\u043e\u0439\u043d\u043e\u0439\xbb \u0432\u0435\u0440\u0441\u0438\u0438 \u043f\u043e\u0432\u044b\u0448\u0430\u0435\u0442 \u043f\u043e\u0434\u0432\u0438\u0436\u043d\u044b\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u2014 \u044d\u0442\u043e \u0437\u0430\u043f\u0443\u0441\u0442\u0438\u043b\u043e \u0441\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u044b\u0439 \u0431\u0443\u043c \u0442\u0440\u0435\u043d\u0430\u0436\u0451\u0440\u043e\u0432 \u043c\u043e\u0437\u0433\u0430 \u0438 \u0434\u0435\u0441\u044f\u0442\u0438\u043b\u0435\u0442\u0438\u0435 \u0441\u043f\u043e\u0440\u043e\u0432.",creator:"\u0417\u0430\u0434\u0430\u0447\u0443 \u043f\u0440\u0438\u043f\u0438\u0441\u044b\u0432\u0430\u044e\u0442 \u0423\u044d\u0439\u043d\u0443 \u041a\u0438\u0440\u0445\u043d\u0435\u0440\u0443 (1958). \u0412\u043b\u0438\u044f\u0442\u0435\u043b\u044c\u043d\u0443\u044e \u0437\u0430\u044f\u0432\u043a\u0443 \u043e \u043f\u043e\u043b\u044c\u0437\u0435 \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0438 \u0432\u044b\u0434\u0432\u0438\u043d\u0443\u043b\u0438 \u0421\u044e\u0437\u0430\u043d\u043d\u0430 \u0419\u0435\u0433\u0433\u0438, \u041c\u0430\u0440\u0442\u0438\u043d \u0411\u0443\u0448\u043a\u044e\u043b\u044c \u0438 \u043a\u043e\u043b\u043b\u0435\u0433\u0438 (2008).",methods:"\u0412\u044b\u0431\u0435\u0440\u0438 N, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u0434\u0435\u0440\u0436\u0438\u0448\u044c \u043d\u0430 ~80% \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u0438, \u0438 \u0434\u0430\u0439 \u0435\u043c\u0443 \u0430\u0434\u0430\u043f\u0442\u0438\u0440\u043e\u0432\u0430\u0442\u044c\u0441\u044f \u2014 \u0432\u0432\u0435\u0440\u0445 \u043f\u0440\u0438 \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u0438, \u0432\u043d\u0438\u0437 \u043f\u0440\u0438 \u0441\u0431\u043e\u044f\u0445. \u0421\u043d\u0430\u0447\u0430\u043b\u0430 \u043e\u0434\u043d\u0430 \u043c\u043e\u0434\u0430\u043b\u044c\u043d\u043e\u0441\u0442\u044c; \u0434\u0432\u043e\u0439\u043d\u0443\u044e (\u043f\u043e\u0437\u0438\u0446\u0438\u044f + \u0437\u0432\u0443\u043a) \u0434\u043e\u0431\u0430\u0432\u043b\u044f\u0439, \u043a\u043e\u0433\u0434\u0430 \u043e\u0434\u0438\u043d\u043e\u0447\u043d\u044b\u0439 n-back \u043f\u043e\u0434 \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u0435\u043c.",duration:"\u0412 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u044f\u0445 \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u0430\u043b\u0438\u0441\u044c \u043f\u0440\u0438\u043c\u0435\u0440\u043d\u043e 15\u201320 \u043c\u0438\u043d\u0443\u0442 \u0432 \u0434\u0435\u043d\u044c \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u043d\u0435\u0434\u0435\u043b\u044c. \u0415\u0441\u043b\u0438 \u0445\u043e\u0447\u0435\u0448\u044c \u0445\u043e\u0442\u044c \u043a\u0430\u043a\u043e\u0439-\u0442\u043e \u043f\u0435\u0440\u0435\u043d\u043e\u0441 \u2014 \u0432\u0430\u0436\u043d\u0430 \u0438\u043c\u0435\u043d\u043d\u043e \u0440\u0435\u0433\u0443\u043b\u044f\u0440\u043d\u043e\u0441\u0442\u044c, \u0430 \u043d\u0435 \u0440\u0435\u0434\u043a\u0438\u0435 \u0434\u043b\u0438\u043d\u043d\u044b\u0435 \u0441\u0435\u0441\u0441\u0438\u0438.",research:"\u0427\u0435\u0441\u0442\u043d\u043e \u043f\u0440\u043e \u0441\u043f\u043e\u0440. \u0420\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442 2008-\u0433\u043e \u0431\u044b\u043b \u044f\u0440\u043a\u0438\u043c, \u043d\u043e \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u0438\u0440\u0443\u0435\u043c\u044b\u0445 \u0440\u0435\u043f\u043b\u0438\u043a (\u043d\u0430\u043f\u0440. Redick, 2013) \u0438 \u043c\u0435\u0442\u0430-\u0430\u043d\u0430\u043b\u0438\u0437\u044b \u043d\u0430\u0448\u043b\u0438 \u043c\u0430\u043b\u043e \u0438\u043b\u0438 \u043d\u0435\u0442 \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0430 \u043d\u0430 \u043f\u043e\u0434\u0432\u0438\u0436\u043d\u044b\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0443 \u0437\u0434\u043e\u0440\u043e\u0432\u044b\u0445 \u0432\u0437\u0440\u043e\u0441\u043b\u044b\u0445. \u0422\u0432\u0451\u0440\u0434\u043e \u043e\u0434\u043d\u043e: \u0442\u044b \u043d\u0430\u0434\u0451\u0436\u043d\u043e \u0443\u043b\u0443\u0447\u0448\u0430\u0435\u0448\u044c \u0441\u0430\u043c n-back \u0438 \u0431\u043b\u0438\u0437\u043a\u0438\u0435 \u0437\u0430\u0434\u0430\u0447\u0438. \xab\u041f\u043e\u0432\u044b\u0448\u0430\u0435\u0442 IQ\xbb \u2014 \u043d\u0435\u0434\u043e\u043a\u0430\u0437\u0430\u043d\u043e.",rec:"\u0422\u0440\u0435\u043d\u0438\u0440\u0443\u0439 \u0440\u0430\u0434\u0438 \u043a\u043e\u043d\u0446\u0435\u043d\u0442\u0440\u0430\u0446\u0438\u0438 \u0438 \u043e\u0431\u043d\u043e\u0432\u043b\u0435\u043d\u0438\u044f \u0438 \u0440\u0430\u0434\u0438 \u0443\u0434\u043e\u0432\u043e\u043b\u044c\u0441\u0442\u0432\u0438\u044f \u043f\u043e\u0431\u0438\u0442\u044c \u0441\u0432\u043e\u0439 \u0443\u0440\u043e\u0432\u0435\u043d\u044c N \u2014 \u043d\u0435 \u0440\u0430\u0434\u0438 \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f \u0432\u044b\u0441\u043e\u043a\u043e\u0433\u043e IQ. \u0414\u0435\u0440\u0436\u0438 \u0430\u0434\u0430\u043f\u0442\u0438\u0432\u043d\u043e\u0441\u0442\u044c \u0438 \u0437\u0430\u043a\u0430\u043d\u0447\u0438\u0432\u0430\u0439 \u0434\u043e \u0442\u043e\u0433\u043e, \u043a\u0430\u043a \u0443\u0441\u0442\u0430\u043b\u043e\u0441\u0442\u044c \u0443\u0431\u044c\u0451\u0442 \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u044c.",faq:[["N-back \u043f\u043e\u0432\u044b\u0448\u0430\u0435\u0442 IQ?","\u0417\u043d\u0430\u043c\u0435\u043d\u0438\u0442\u043e\u0435 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u0435 2008-\u0433\u043e \u0433\u043e\u0432\u043e\u0440\u0438\u043b\u043e, \u0447\u0442\u043e \u043c\u043e\u0436\u0435\u0442; \u043f\u043e\u0437\u0434\u043d\u0438\u0435 \u0440\u0435\u043f\u043b\u0438\u043a\u0438 \u0432 \u043e\u0441\u043d\u043e\u0432\u043d\u043e\u043c \u043d\u0435 \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0434\u0438\u043b\u0438. \u0411\u0435\u0437\u043e\u043f\u0430\u0441\u043d\u043e: \u0442\u044b \u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0448\u044c\u0441\u044f \u043b\u0443\u0447\u0448\u0435 \u0432 n-back \u0438 \u0437\u0430\u0434\u0430\u0447\u0430\u0445 \u0440\u0430\u0431\u043e\u0447\u0435\u0439 \u043f\u0430\u043c\u044f\u0442\u0438."],["\u041e\u0434\u0438\u043d\u043e\u0447\u043d\u044b\u0439 \u0438\u043b\u0438 \u0434\u0432\u043e\u0439\u043d\u043e\u0439?","\u041d\u0430\u0447\u043d\u0438 \u0441 \u043e\u0434\u0438\u043d\u043e\u0447\u043d\u043e\u0433\u043e. \u0414\u0432\u043e\u0439\u043d\u043e\u0439 (\u043f\u043e\u0437\u0438\u0446\u0438\u044f + \u0437\u0432\u0443\u043a) \u0441\u043b\u043e\u0436\u043d\u0435\u0435 \u2014 \u0438\u043c\u0435\u043d\u043d\u043e \u043e\u043d \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u043b\u0441\u044f \u0432 \u043e\u0440\u0438\u0433\u0438\u043d\u0430\u043b\u044c\u043d\u044b\u0445 \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0430\u0445."],["\u041a\u043e\u0433\u0434\u0430 \u0431\u0443\u0434\u0435\u0442 \u043f\u0440\u043e\u0433\u0440\u0435\u0441\u0441?","\u041f\u0440\u043e\u0433\u0440\u0435\u0441\u0441 \u0432 \u0441\u0430\u043c\u043e\u0439 \u0437\u0430\u0434\u0430\u0447\u0435 \u043e\u0431\u044b\u0447\u043d\u043e \u0432\u0438\u0434\u0435\u043d \u0437\u0430 \u0434\u043d\u0438; \u0431\u043e\u043b\u0435\u0435 \u0448\u0438\u0440\u043e\u043a\u0438\u0439 \u043f\u0435\u0440\u0435\u043d\u043e\u0441, \u0435\u0441\u043b\u0438 \u043e\u043d \u0435\u0441\u0442\u044c, \u0442\u0440\u0435\u0431\u0443\u0435\u0442 \u043d\u0435\u0434\u0435\u043b\u044c \u0435\u0436\u0435\u0434\u043d\u0435\u0432\u043d\u043e\u0439 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u0438."]],variants:"\u041e\u0434\u0438\u043d\u043e\u0447\u043d\u044b\u0439 n-back (\u043e\u0434\u0438\u043d \u043f\u043e\u0442\u043e\u043a); \u0434\u0432\u043e\u0439\u043d\u043e\u0439 (\u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0439 + \u0441\u043b\u0443\u0445\u043e\u0432\u043e\u0439); \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u044b \u0441 \u043f\u043e\u0437\u0438\u0446\u0438\u0435\u0439, \u0431\u0443\u043a\u0432\u0430\u043c\u0438, \u0446\u0432\u0435\u0442\u043e\u043c \u0438\u043b\u0438 \u0437\u0432\u0443\u043a\u043e\u043c. \u0421\u043b\u043e\u0436\u043d\u043e\u0441\u0442\u044c \u0440\u0430\u0441\u0442\u0451\u0442 \u043f\u043e\u0432\u044b\u0448\u0435\u043d\u0438\u0435\u043c N."},en:{about:"A stream of stimuli appears one at a time; you respond whenever the current one matches the one shown N steps back. As N climbs from 1 to 2 to 3, the load on working memory rises steeply.",benefit:"Working-memory capacity, updating (constantly swapping old items for new), and resistance to interference \u2014 the core \"mental juggling\" behind focus and reasoning.",history:"The n-back procedure was introduced in 1958 as a laboratory measure of working memory. It became famous in 2008, when a study reported that training a harder \"dual\" version raised fluid intelligence \u2014 sparking the modern brain-training boom and a decade of debate.",creator:"The task is credited to Wayne Kirchner (1958). The influential training claim came from Susanne Jaeggi, Martin Buschkuehl and colleagues (2008).",methods:"Pick an N you can hold at about 80% accuracy and let it adapt \u2014 up when you are accurate, down when you slip. Train single-modality first; add the dual (position + sound) version only once single n-back feels controlled.",duration:"Training studies used roughly 15\u201320 minutes a day across several weeks. If you want any chance of transfer, that consistency \u2014 not the occasional long session \u2014 is the variable that mattered.",research:"Be honest about the controversy. The 2008 result was exciting, but several well-controlled replications (e.g. Redick 2013) and meta-analyses found little or no transfer to fluid intelligence in healthy adults. What is solid: you reliably improve on n-back and closely related tasks. Treat \"raises IQ\" as unproven.",rec:"Train it for focus and updating, and for the satisfaction of beating your own N-level \u2014 not on a promise of a higher IQ. Keep it adaptive, and stop before fatigue wrecks your accuracy.",faq:[["Does n-back raise IQ?","The famous 2008 study said it could; later replications mostly did not confirm it. The safe claim: you get better at n-back and working-memory tasks."],["Single or dual n-back?","Start single. Dual (position + audio) is harder and is the version used in the original training studies."],["How long until I improve?","Improvement on the task itself usually shows within days; any broader transfer, if it happens at all, needs weeks of daily practice."]],variants:"Single n-back (one stream); dual n-back (visual + auditory); and position, letter, colour or sound variants. Difficulty scales by raising N."},es:{about:"Aparece un flujo de est\xedmulos de uno en uno; respondes cada vez que el actual coincide con el que se mostr\xf3 N pasos atr\xe1s. A medida que N sube de 1 a 2 y a 3, la carga sobre la memoria de trabajo aumenta de forma pronunciada.",benefit:"La capacidad de la memoria de trabajo, la actualizaci\xf3n (cambiar constantemente elementos viejos por nuevos) y la resistencia a la interferencia: los \"malabares mentales\" esenciales que hay detr\xe1s de la concentraci\xf3n y el razonamiento.",history:"El procedimiento n-back se introdujo en 1958 como medida de laboratorio de la memoria de trabajo. Se hizo famoso en 2008, cuando un estudio inform\xf3 de que entrenar una versi\xf3n \"doble\" m\xe1s dif\xedcil elevaba la inteligencia fluida, lo que desat\xf3 el auge moderno del entrenamiento cerebral y una d\xe9cada de debate.",creator:"La tarea se atribuye a Wayne Kirchner (1958). La influyente afirmaci\xf3n sobre el entrenamiento provino de Susanne Jaeggi, Martin Buschkuehl y colaboradores (2008).",methods:"Elige un N que puedas mantener en torno al 80% de precisi\xf3n y deja que se adapte: sube cuando aciertas, baja cuando fallas. Entrena primero en una sola modalidad; a\xf1ade la versi\xf3n doble (posici\xf3n + sonido) solo cuando el n-back simple te resulte controlado.",duration:"Los estudios de entrenamiento usaron unos 15 a 20 minutos al d\xeda durante varias semanas. Si quieres alguna posibilidad de transferencia, esa constancia -y no la sesi\xf3n larga ocasional- fue la variable que import\xf3.",research:"S\xe9 honesto sobre la controversia. El resultado de 2008 fue emocionante, pero varias r\xe9plicas bien controladas (por ejemplo, Redick 2013) y metaan\xe1lisis encontraron poca o ninguna transferencia a la inteligencia fluida en adultos sanos. Lo que s\xed es s\xf3lido: mejoras de forma fiable en el n-back y en tareas muy relacionadas. Toma el \"eleva el CI\" como no demostrado.",rec:"Entr\xe9nalo por la concentraci\xf3n y la actualizaci\xf3n, y por la satisfacci\xf3n de superar tu propio nivel de N, no por la promesa de un CI m\xe1s alto. Mantenlo adaptativo y detente antes de que la fatiga arruine tu precisi\xf3n.",faq:[["\xbfEl n-back eleva el CI?","El famoso estudio de 2008 dijo que pod\xeda; las r\xe9plicas posteriores en su mayor\xeda no lo confirmaron. La afirmaci\xf3n segura: mejoras en el n-back y en las tareas de memoria de trabajo."],["\xbfN-back simple o doble?","Empieza por el simple. El doble (posici\xf3n + audio) es m\xe1s dif\xedcil y es la versi\xf3n usada en los estudios de entrenamiento originales."],["\xbfCu\xe1nto tardo en mejorar?","La mejora en la propia tarea suele notarse en cuesti\xf3n de d\xedas; cualquier transferencia m\xe1s amplia, si llega a ocurrir, necesita semanas de pr\xe1ctica diaria."]],variants:"N-back simple (un solo flujo); n-back doble (visual + auditivo); y variantes de posici\xf3n, letra, color o sonido. La dificultad escala al aumentar N."},de:{about:"Ein Strom von Reizen erscheint nacheinander; du reagierst immer dann, wenn der aktuelle mit dem \xfcbereinstimmt, der N Schritte zuvor gezeigt wurde. Steigt N von 1 auf 2 auf 3, w\xe4chst die Belastung des Arbeitsged\xe4chtnisses steil an.",benefit:"Kapazit\xe4t des Arbeitsged\xe4chtnisses, Aktualisieren (st\xe4ndiges Austauschen alter Elemente gegen neue) und Widerstand gegen Interferenz \u2013 das zentrale \u201egeistige Jonglieren\u201c hinter Konzentration und Denken.",history:"Das n-back-Verfahren wurde 1958 als Laborma\xdf f\xfcr das Arbeitsged\xe4chtnis eingef\xfchrt. Ber\xfchmt wurde es 2008, als eine Studie berichtete, dass das Training einer schwereren \u201edualen\u201c Variante die fluide Intelligenz steigere \u2013 was den modernen Gehirntraining-Boom und ein Jahrzehnt der Debatte ausl\xf6ste.",creator:"Die Aufgabe wird Wayne Kirchner (1958) zugeschrieben. Die einflussreiche Trainingsbehauptung stammt von Susanne Jaeggi, Martin Buschkuehl und Kollegen (2008).",methods:"W\xe4hle ein N, das du bei etwa 80 % Treffsicherheit halten kannst, und lass es sich anpassen \u2013 hinauf, wenn du treffsicher bist, hinab, wenn du nachl\xe4sst. Trainiere zuerst eine einzelne Modalit\xe4t; f\xfcge die duale Variante (Position + Ton) erst hinzu, wenn sich das einfache n-back kontrolliert anf\xfchlt.",duration:"Trainingsstudien nutzten etwa 15\u201320 Minuten am Tag \xfcber mehrere Wochen. Wenn du \xfcberhaupt eine Chance auf Transfer willst, ist diese Best\xe4ndigkeit \u2013 nicht die gelegentliche lange Sitzung \u2013 die Gr\xf6\xdfe, auf die es ankam.",research:"Sei ehrlich \xfcber die Kontroverse. Das Ergebnis von 2008 war aufregend, doch mehrere gut kontrollierte Replikationen (z. B. Redick 2013) und Meta-Analysen fanden bei gesunden Erwachsenen kaum oder keinen Transfer auf die fluide Intelligenz. Solide ist: Im n-back und eng verwandten Aufgaben verbesserst du dich verl\xe4sslich. \u201eSteigert den IQ\u201c als unbelegt behandeln.",rec:"Trainiere es f\xfcr Konzentration und Aktualisieren und f\xfcr die Genugtuung, dein eigenes N-Niveau zu \xfcbertreffen \u2013 nicht auf das Versprechen eines h\xf6heren IQ. Halte es anpassend und h\xf6r auf, bevor Erm\xfcdung deine Treffsicherheit ruiniert.",faq:[["Steigert n-back den IQ?","Die ber\xfchmte Studie von 2008 sagte, es k\xf6nne \u2013 sp\xe4tere Replikationen best\xe4tigten es meist nicht. Die sichere Aussage: Du wirst besser im n-back und in Aufgaben des Arbeitsged\xe4chtnisses."],["Einfaches oder duales n-back?","Beginne einfach. Dual (Position + Ton) ist schwerer und ist die Variante, die in den urspr\xfcnglichen Trainingsstudien verwendet wurde."],["Wie lange dauert es, bis ich mich verbessere?","Eine Verbesserung in der Aufgabe selbst zeigt sich meist innerhalb von Tagen; ein breiterer Transfer braucht, falls er \xfcberhaupt eintritt, Wochen t\xe4glichen \xdcbens."]],variants:"Einfaches n-back (ein Strom); duales n-back (visuell + auditiv); sowie Varianten mit Position, Buchstaben, Farbe oder Ton. Die Schwierigkeit skaliert durch Erh\xf6hen von N."},pt:{about:"Um fluxo de est\xedmulos aparece um de cada vez; voc\xea responde sempre que o atual coincide com o que foi mostrado N passos atr\xe1s. \xc0 medida que N sobe de 1 para 2 e para 3, a carga sobre a mem\xf3ria de trabalho aumenta de forma acentuada.",benefit:"Capacidade da mem\xf3ria de trabalho, atualiza\xe7\xe3o (trocar constantemente itens antigos por novos) e resist\xeancia \xe0 interfer\xeancia \u2014 o \"malabarismo mental\" central que est\xe1 por tr\xe1s da concentra\xe7\xe3o e do racioc\xednio.",history:"O procedimento n-back foi introduzido em 1958 como medida laboratorial da mem\xf3ria de trabalho. Ficou famoso em 2008, quando um estudo relatou que treinar uma vers\xe3o \"dupla\" mais dif\xedcil elevava a intelig\xeancia fluida \u2014 dando in\xedcio ao boom moderno do treino cerebral e a uma d\xe9cada de debate.",creator:"A tarefa \xe9 creditada a Wayne Kirchner (1958). A influente alega\xe7\xe3o sobre o treino veio de Susanne Jaeggi, Martin Buschkuehl e colegas (2008).",methods:"Escolha um N que voc\xea consiga manter com cerca de 80% de precis\xe3o e deixe-o se adaptar \u2014 sobe quando voc\xea est\xe1 preciso, desce quando voc\xea falha. Treine primeiro em uma s\xf3 modalidade; acrescente a vers\xe3o dupla (posi\xe7\xe3o + som) s\xf3 depois que o n-back simples parecer sob controle.",duration:"Os estudos de treino usaram cerca de 15 a 20 minutos por dia ao longo de v\xe1rias semanas. Se voc\xea quiser alguma chance de transfer\xeancia, \xe9 essa const\xe2ncia \u2014 e n\xe3o a sess\xe3o longa ocasional \u2014 a vari\xe1vel que importou.",research:"Seja honesto sobre a controv\xe9rsia. O resultado de 2008 foi empolgante, mas v\xe1rias replica\xe7\xf5es bem controladas (por exemplo, Redick 2013) e meta-an\xe1lises encontraram pouca ou nenhuma transfer\xeancia para a intelig\xeancia fluida em adultos saud\xe1veis. O que \xe9 s\xf3lido: voc\xea melhora de forma confi\xe1vel no n-back e em tarefas muito pr\xf3ximas. Encare o \"aumenta o QI\" como n\xe3o comprovado.",rec:"Treine-o pela concentra\xe7\xe3o e pela atualiza\xe7\xe3o, e pela satisfa\xe7\xe3o de superar o seu pr\xf3prio n\xedvel de N \u2014 n\xe3o pela promessa de um QI mais alto. Mantenha-o adaptativo e pare antes que a fadiga arru\xedne sua precis\xe3o.",faq:[["O n-back aumenta o QI?","O famoso estudo de 2008 disse que poderia; replica\xe7\xf5es posteriores em geral n\xe3o confirmaram. A alega\xe7\xe3o segura: voc\xea fica melhor no n-back e em tarefas de mem\xf3ria de trabalho."],["N-back simples ou duplo?","Comece pelo simples. O duplo (posi\xe7\xe3o + \xe1udio) \xe9 mais dif\xedcil e \xe9 a vers\xe3o usada nos estudos de treino originais."],["Quanto tempo at\xe9 eu melhorar?","A melhora na pr\xf3pria tarefa costuma aparecer em poucos dias; qualquer transfer\xeancia mais ampla, se \xe9 que acontece, exige semanas de pr\xe1tica di\xe1ria."]],variants:"N-back simples (um fluxo); n-back duplo (visual + auditivo); e variantes de posi\xe7\xe3o, letra, cor ou som. A dificuldade escala ao aumentar N."},hi:{about:"\u090f\u0915-\u090f\u0915 \u0915\u0930\u0915\u0947 \u0909\u0924\u094d\u0924\u0947\u091c\u0928\u093e\u0913\u0902 \u0915\u0940 \u0927\u093e\u0930\u093e \u0938\u093e\u092e\u0928\u0947 \u0906\u0924\u0940 \u0939\u0948; \u091c\u092c \u092d\u0940 \u092e\u094c\u091c\u0942\u0926\u093e \u0909\u0924\u094d\u0924\u0947\u091c\u0928\u093e N \u0915\u0926\u092e \u092a\u0940\u091b\u0947 \u0926\u093f\u0916\u093e\u0908 \u0917\u0908 \u0909\u0924\u094d\u0924\u0947\u091c\u0928\u093e \u0938\u0947 \u092e\u0947\u0932 \u0916\u093e\u090f, \u0924\u092c \u0906\u092a \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0926\u0947\u0924\u0947 \u0939\u0948\u0902\u0964 \u091c\u0948\u0938\u0947-\u091c\u0948\u0938\u0947 N, 1 \u0938\u0947 2 \u0914\u0930 3 \u0924\u0915 \u091a\u0922\u093c\u0924\u093e \u0939\u0948, \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932 \u0938\u094d\u092e\u0943\u0924\u093f \u092a\u0930 \u092c\u094b\u091d \u0924\u0947\u091c\u093c\u0940 \u0938\u0947 \u092c\u0922\u093c\u0924\u093e \u091c\u093e\u0924\u093e \u0939\u0948\u0964",benefit:"\u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932 \u0938\u094d\u092e\u0943\u0924\u093f \u0915\u0940 \u0915\u094d\u0937\u092e\u0924\u093e, \u0905\u0926\u094d\u092f\u0924\u0928 \u0915\u0930\u0928\u093e (\u0932\u0917\u093e\u0924\u093e\u0930 \u092a\u0941\u0930\u093e\u0928\u0940 \u091a\u0940\u091c\u093c\u094b\u0902 \u0915\u094b \u0928\u0908 \u0938\u0947 \u092c\u0926\u0932\u0924\u0947 \u0930\u0939\u0928\u093e), \u0914\u0930 \u0939\u0938\u094d\u0924\u0915\u094d\u0937\u0947\u092a \u0915\u0947 \u092a\u094d\u0930\u0924\u093f \u092a\u094d\u0930\u0924\u093f\u0930\u094b\u0927 \u2014 \u0935\u0939\u0940 \"\u092e\u093e\u0928\u0938\u093f\u0915 \u091c\u0941\u0917\u0932\u092c\u0902\u0926\u0940\" \u091c\u094b \u090f\u0915\u093e\u0917\u094d\u0930\u0924\u093e \u0914\u0930 \u0924\u0930\u094d\u0915 \u0915\u0947 \u092a\u0940\u091b\u0947 \u0939\u0948\u0964",history:"n-back \u0935\u093f\u0927\u093f \u0915\u094b 1958 \u092e\u0947\u0902 \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932 \u0938\u094d\u092e\u0943\u0924\u093f \u0915\u0947 \u090f\u0915 \u092a\u094d\u0930\u092f\u094b\u0917\u0936\u093e\u0932\u093e \u092e\u093e\u092a \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u092a\u0947\u0936 \u0915\u093f\u092f\u093e \u0917\u092f\u093e\u0964 \u092f\u0939 2008 \u092e\u0947\u0902 \u092a\u094d\u0930\u0938\u093f\u0926\u094d\u0927 \u0939\u0941\u0908, \u091c\u092c \u090f\u0915 \u0905\u0927\u094d\u092f\u092f\u0928 \u0928\u0947 \u092c\u0924\u093e\u092f\u093e \u0915\u093f \u0907\u0938\u0915\u0947 \u0915\u0920\u093f\u0928 \"\u0926\u094b\u0939\u0930\u0947\" \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0924\u0930\u0932 \u092c\u0941\u0926\u094d\u0927\u093f (\u092b\u094d\u0932\u0942\u0907\u0921 \u0907\u0902\u091f\u0947\u0932\u093f\u091c\u0947\u0902\u0938) \u092c\u0922\u093c\u093e\u0924\u093e \u0939\u0948 \u2014 \u091c\u093f\u0938\u0928\u0947 \u0906\u0927\u0941\u0928\u093f\u0915 \u092c\u094d\u0930\u0947\u0928-\u091f\u094d\u0930\u0947\u0928\u093f\u0902\u0917 \u0915\u0940 \u0932\u0939\u0930 \u0914\u0930 \u090f\u0915 \u0926\u0936\u0915 \u0915\u0940 \u092c\u0939\u0938 \u0915\u094b \u091c\u0928\u094d\u092e \u0926\u093f\u092f\u093e\u0964",creator:"\u0907\u0938 \u0915\u093e\u0930\u094d\u092f \u0915\u093e \u0936\u094d\u0930\u0947\u092f \u0935\u0947\u0928 \u0915\u093f\u0930\u094d\u0936\u0928\u0930 (Wayne Kirchner, 1958) \u0915\u094b \u091c\u093e\u0924\u093e \u0939\u0948\u0964 \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u0915\u093e \u092a\u094d\u0930\u092d\u093e\u0935\u0936\u093e\u0932\u0940 \u0926\u093e\u0935\u093e \u0938\u0941\u091c\u093c\u0948\u0928 \u092f\u0947\u0917\u0940 (Susanne Jaeggi), \u092e\u093e\u0930\u094d\u091f\u093f\u0928 \u092c\u0941\u0936\u0915\u0941\u090f\u0932 \u0914\u0930 \u0938\u0939\u092f\u094b\u0917\u093f\u092f\u094b\u0902 (2008) \u0915\u0940 \u0913\u0930 \u0938\u0947 \u0906\u092f\u093e\u0964",methods:"\u0910\u0938\u093e N \u091a\u0941\u0928\u0947\u0902 \u091c\u093f\u0938\u0947 \u0906\u092a \u0932\u0917\u092d\u0917 80% \u0938\u091f\u0940\u0915\u0924\u093e \u092a\u0930 \u092c\u0928\u093e\u090f \u0930\u0916 \u0938\u0915\u0947\u0902 \u0914\u0930 \u0909\u0938\u0947 \u0905\u0928\u0941\u0915\u0942\u0932\u093f\u0924 \u0939\u094b\u0928\u0947 \u0926\u0947\u0902 \u2014 \u0938\u091f\u0940\u0915 \u0930\u0939\u0928\u0947 \u092a\u0930 \u090a\u092a\u0930, \u091a\u0942\u0915\u0928\u0947 \u092a\u0930 \u0928\u0940\u091a\u0947\u0964 \u092a\u0939\u0932\u0947 \u090f\u0915\u0932-\u0907\u0902\u0926\u094d\u0930\u093f\u092f (single) \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0930\u0947\u0902; \u0926\u094b\u0939\u0930\u093e (\u0938\u094d\u0925\u093e\u0928 + \u0927\u094d\u0935\u0928\u093f) \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0924\u092d\u0940 \u091c\u094b\u0921\u093c\u0947\u0902 \u091c\u092c \u090f\u0915\u0932 n-back \u0928\u093f\u092f\u0902\u0924\u094d\u0930\u0923 \u092e\u0947\u0902 \u0932\u0917\u0928\u0947 \u0932\u0917\u0947\u0964",duration:"\u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u0905\u0927\u094d\u092f\u092f\u0928\u094b\u0902 \u092e\u0947\u0902 \u0915\u0908 \u0939\u092b\u093c\u094d\u0924\u094b\u0902 \u0924\u0915 \u0930\u094b\u091c\u093c \u0932\u0917\u092d\u0917 15\u201320 \u092e\u093f\u0928\u091f \u0932\u0917\u093e\u090f \u0917\u090f\u0964 \u0905\u0917\u0930 \u0906\u092a \u0915\u093f\u0938\u0940 \u092d\u0940 \u0939\u0938\u094d\u0924\u093e\u0902\u0924\u0930\u0923 (transfer) \u0915\u0940 \u0909\u092e\u094d\u092e\u0940\u0926 \u0930\u0916\u0924\u0947 \u0939\u0948\u0902, \u0924\u094b \u0935\u0939\u0940 \u0928\u093f\u092f\u092e\u093f\u0924\u0924\u093e \u2014 \u0928 \u0915\u093f \u0915\u092d\u0940-\u0915\u092d\u093e\u0930 \u0915\u093e \u0932\u0902\u092c\u093e \u0938\u0924\u094d\u0930 \u2014 \u0905\u0938\u0932\u0940 \u0928\u093f\u0930\u094d\u0923\u093e\u092f\u0915 \u091a\u0940\u091c\u093c \u0938\u093e\u092c\u093f\u0924 \u0939\u0941\u0908\u0964",research:"\u0935\u093f\u0935\u093e\u0926 \u0915\u0947 \u092c\u093e\u0930\u0947 \u092e\u0947\u0902 \u0908\u092e\u093e\u0928\u0926\u093e\u0930 \u0930\u0939\u0947\u0902\u0964 2008 \u0915\u093e \u0928\u0924\u0940\u091c\u093e \u0930\u094b\u092e\u093e\u0902\u091a\u0915 \u0925\u093e, \u092a\u0930 \u0915\u0908 \u0938\u0941\u0928\u093f\u092f\u0902\u0924\u094d\u0930\u093f\u0924 \u092a\u0941\u0928\u0930\u093e\u0935\u0943\u0924\u094d\u0924\u093f\u092f\u094b\u0902 (\u091c\u0948\u0938\u0947 Redick 2013) \u0914\u0930 \u092e\u0947\u091f\u093e-\u0935\u093f\u0936\u094d\u0932\u0947\u0937\u0923\u094b\u0902 \u0928\u0947 \u0938\u094d\u0935\u0938\u094d\u0925 \u0935\u092f\u0938\u094d\u0915\u094b\u0902 \u092e\u0947\u0902 \u0924\u0930\u0932 \u092c\u0941\u0926\u094d\u0927\u093f \u0924\u0915 \u0915\u094b\u0908 \u092f\u093e \u092c\u0939\u0941\u0924 \u0915\u092e \u0939\u0938\u094d\u0924\u093e\u0902\u0924\u0930\u0923 \u092a\u093e\u092f\u093e\u0964 \u091c\u094b \u092a\u0915\u094d\u0915\u093e \u0939\u0948: n-back \u0914\u0930 \u0909\u0938\u0938\u0947 \u091c\u0941\u0921\u093c\u0947 \u0915\u093e\u0930\u094d\u092f\u094b\u0902 \u092e\u0947\u0902 \u0906\u092a \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0930\u0942\u092a \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902\u0964 \"IQ \u092c\u0922\u093c\u093e\u0924\u093e \u0939\u0948\" \u0915\u094b \u0905\u092a\u094d\u0930\u092e\u093e\u0923\u093f\u0924 \u092e\u093e\u0928\u0947\u0902\u0964",rec:"\u0907\u0938\u0947 \u090f\u0915\u093e\u0917\u094d\u0930\u0924\u093e \u0914\u0930 \u0905\u0926\u094d\u092f\u0924\u0928 \u0915\u0947 \u0932\u093f\u090f, \u0914\u0930 \u0905\u092a\u0928\u0947 \u0939\u0940 N-\u0938\u094d\u0924\u0930 \u0915\u094b \u092e\u093e\u0924 \u0926\u0947\u0928\u0947 \u0915\u0947 \u0938\u0902\u0924\u094b\u0937 \u0915\u0947 \u0932\u093f\u090f \u0938\u093e\u0927\u0947\u0902 \u2014 \u0915\u093f\u0938\u0940 \u090a\u0901\u091a\u0947 IQ \u0915\u0947 \u0935\u093e\u0926\u0947 \u0915\u0947 \u092d\u0930\u094b\u0938\u0947 \u0928\u0939\u0940\u0902\u0964 \u0907\u0938\u0947 \u0905\u0928\u0941\u0915\u0942\u0932\u0940 \u0930\u0916\u0947\u0902, \u0914\u0930 \u0925\u0915\u093e\u0928 \u0915\u0947 \u0906\u092a\u0915\u0940 \u0938\u091f\u0940\u0915\u0924\u093e \u092c\u0930\u094d\u092c\u093e\u0926 \u0915\u0930\u0928\u0947 \u0938\u0947 \u092a\u0939\u0932\u0947 \u0930\u0941\u0915 \u091c\u093e\u090f\u0901\u0964",faq:[["\u0915\u094d\u092f\u093e n-back IQ \u092c\u0922\u093c\u093e\u0924\u093e \u0939\u0948?","\u092e\u0936\u0939\u0942\u0930 2008 \u0915\u0947 \u0905\u0927\u094d\u092f\u092f\u0928 \u0928\u0947 \u0915\u0939\u093e \u0915\u093f \u092c\u0922\u093c\u093e \u0938\u0915\u0924\u093e \u0939\u0948; \u092c\u093e\u0926 \u0915\u0940 \u092a\u0941\u0928\u0930\u093e\u0935\u0943\u0924\u094d\u0924\u093f\u092f\u094b\u0902 \u0928\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e\u0924\u0930 \u0907\u0938\u0915\u0940 \u092a\u0941\u0937\u094d\u091f\u093f \u0928\u0939\u0940\u0902 \u0915\u0940\u0964 \u0938\u0941\u0930\u0915\u094d\u0937\u093f\u0924 \u0926\u093e\u0935\u093e: \u0906\u092a n-back \u0914\u0930 \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932-\u0938\u094d\u092e\u0943\u0924\u093f \u0915\u093e\u0930\u094d\u092f\u094b\u0902 \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902\u0964"],["\u090f\u0915\u0932 n-back \u092f\u093e \u0926\u094b\u0939\u0930\u093e?","\u090f\u0915\u0932 \u0938\u0947 \u0936\u0941\u0930\u0942 \u0915\u0930\u0947\u0902\u0964 \u0926\u094b\u0939\u0930\u093e (\u0938\u094d\u0925\u093e\u0928 + \u0927\u094d\u0935\u0928\u093f) \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0915\u0920\u093f\u0928 \u0939\u0948 \u0914\u0930 \u092e\u0942\u0932 \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u0905\u0927\u094d\u092f\u092f\u0928\u094b\u0902 \u092e\u0947\u0902 \u092f\u0939\u0940 \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0939\u0941\u0906 \u0925\u093e\u0964"],["\u092c\u0947\u0939\u0924\u0930 \u0939\u094b\u0928\u0947 \u092e\u0947\u0902 \u0915\u093f\u0924\u0928\u093e \u0938\u092e\u092f \u0932\u0917\u0947\u0917\u093e?","\u0915\u093e\u0930\u094d\u092f \u092e\u0947\u0902 \u0939\u0940 \u0938\u0941\u0927\u093e\u0930 \u0906\u092e\u0924\u094c\u0930 \u092a\u0930 \u0915\u0941\u091b \u0926\u093f\u0928\u094b\u0902 \u092e\u0947\u0902 \u0926\u093f\u0916\u0924\u093e \u0939\u0948; \u0915\u094b\u0908 \u0935\u094d\u092f\u093e\u092a\u0915 \u0939\u0938\u094d\u0924\u093e\u0902\u0924\u0930\u0923, \u0905\u0917\u0930 \u0939\u094b\u0924\u093e \u092d\u0940 \u0939\u0948, \u0924\u094b \u0909\u0938\u0915\u0947 \u0932\u093f\u090f \u0939\u092b\u093c\u094d\u0924\u094b\u0902 \u0915\u0947 \u0930\u094b\u091c\u093c\u093e\u0928\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0940 \u091c\u093c\u0930\u0942\u0930\u0924 \u0939\u094b\u0924\u0940 \u0939\u0948\u0964"]],variants:"\u090f\u0915\u0932 n-back (\u090f\u0915 \u0927\u093e\u0930\u093e); \u0926\u094b\u0939\u0930\u093e n-back (\u0926\u0943\u0936\u094d\u092f + \u0936\u094d\u0930\u0935\u094d\u092f); \u0914\u0930 \u0938\u094d\u0925\u093e\u0928, \u0905\u0915\u094d\u0937\u0930, \u0930\u0902\u0917 \u092f\u093e \u0927\u094d\u0935\u0928\u093f \u0935\u093e\u0932\u0947 \u0938\u0902\u0938\u094d\u0915\u0930\u0923\u0964 \u0915\u0920\u093f\u0928\u093e\u0908 N \u092c\u0922\u093c\u093e\u0915\u0930 \u092c\u0926\u0932\u0924\u0940 \u0939\u0948\u0964"},zh:{about:"\u523a\u6fc0\u4e00\u4e2a\u63a5\u4e00\u4e2a\u5730\u4f9d\u6b21\u51fa\u73b0\uff1b\u6bcf\u5f53\u5f53\u524d\u523a\u6fc0\u4e0e N \u6b65\u4e4b\u524d\u51fa\u73b0\u8fc7\u7684\u90a3\u4e00\u4e2a\u76f8\u540c\u65f6\uff0c\u4f60\u5c31\u4f5c\u51fa\u53cd\u5e94\u3002\u968f\u7740 N \u4ece 1 \u5347\u5230 2\u3001\u518d\u5230 3\uff0c\u5de5\u4f5c\u8bb0\u5fc6\u7684\u8d1f\u8377\u9661\u7136\u52a0\u91cd\u3002",benefit:"\u5de5\u4f5c\u8bb0\u5fc6\u5bb9\u91cf\u3001\u66f4\u65b0\u80fd\u529b\uff08\u4e0d\u65ad\u5730\u628a\u65e7\u6761\u76ee\u6362\u6210\u65b0\u6761\u76ee\uff09\uff0c\u4ee5\u53ca\u6297\u5e72\u6270\u80fd\u529b\u2014\u2014\u8fd9\u6b63\u662f\u4e13\u6ce8\u548c\u63a8\u7406\u80cc\u540e\u6838\u5fc3\u7684\u201c\u5fc3\u7406\u6742\u800d\u201d\u3002",history:"N-back \u6d41\u7a0b\u4e8e 1958 \u5e74\u4f5c\u4e3a\u4e00\u79cd\u5de5\u4f5c\u8bb0\u5fc6\u7684\u5b9e\u9a8c\u5ba4\u6d4b\u91cf\u624b\u6bb5\u88ab\u5f15\u5165\u3002\u5b83\u5728 2008 \u5e74\u58f0\u540d\u5927\u566a\uff0c\u5f53\u65f6\u4e00\u9879\u7814\u7a76\u62a5\u544a\u79f0\uff0c\u8bad\u7ec3\u66f4\u96be\u7684\u201c\u53cc\u91cd\u201d\u7248\u672c\u80fd\u63d0\u5347\u6d41\u4f53\u667a\u529b\u2014\u2014\u7531\u6b64\u70b9\u71c3\u4e86\u73b0\u4ee3\u8111\u529b\u8bad\u7ec3\u70ed\u6f6e\u548c\u957f\u8fbe\u5341\u5e74\u7684\u4e89\u8bba\u3002",creator:"\u8fd9\u9879\u4efb\u52a1\u5f52\u529f\u4e8e Wayne Kirchner\uff081958\uff09\u3002\u90a3\u4e2a\u9887\u5177\u5f71\u54cd\u529b\u7684\u8bad\u7ec3\u8bba\u65ad\u5219\u51fa\u81ea Susanne Jaeggi\u3001Martin Buschkuehl \u53ca\u5176\u540c\u4e8b\uff082008\uff09\u3002",methods:"\u9009\u4e00\u4e2a\u4f60\u80fd\u7ef4\u6301\u5728\u7ea6 80% \u51c6\u786e\u7387\u7684 N\uff0c\u5e76\u8ba9\u5b83\u81ea\u9002\u5e94\u2014\u2014\u51c6\u7684\u65f6\u5019\u5f80\u4e0a\u52a0\uff0c\u5931\u624b\u7684\u65f6\u5019\u5f80\u4e0b\u964d\u3002\u5148\u8bad\u7ec3\u5355\u4e00\u901a\u9053\uff1b\u53ea\u6709\u5f53\u4f60\u89c9\u5f97\u5355\u4e00 n-back \u5df2\u80fd\u638c\u63a7\u65f6\uff0c\u518d\u52a0\u5165\u53cc\u91cd\uff08\u4f4d\u7f6e + \u58f0\u97f3\uff09\u7248\u672c\u3002",duration:"\u8bad\u7ec3\u7814\u7a76\u91c7\u7528\u7684\u662f\u5927\u7ea6\u6bcf\u5929 15 \u5230 20 \u5206\u949f\u3001\u6301\u7eed\u6570\u5468\u3002\u5982\u679c\u4f60\u60f3\u7ed9\u8fc1\u79fb\u7559\u4e00\u4e1d\u53ef\u80fd\uff0c\u5173\u952e\u53d8\u91cf\u6b63\u662f\u8fd9\u79cd\u6301\u7eed\u6027\uff0c\u800c\u975e\u5076\u5c14\u7684\u4e00\u6b21\u957f\u65f6\u6bb5\u7ec3\u4e60\u3002",research:"\u5bf9\u4e89\u8bae\u8981\u5766\u8bda\u30022008 \u5e74\u7684\u7ed3\u679c\u4ee4\u4eba\u632f\u594b\uff0c\u4f46\u82e5\u5e72\u8bbe\u6709\u4e25\u683c\u5bf9\u7167\u7684\u91cd\u590d\u5b9e\u9a8c\uff08\u5982 Redick 2013\uff09\u548c\u5143\u5206\u6790\u53d1\u73b0\uff0c\u5728\u5065\u5eb7\u6210\u5e74\u4eba\u8eab\u4e0a\u51e0\u4e4e\u6ca1\u6709\u3001\u751a\u81f3\u5b8c\u5168\u6ca1\u6709\u5411\u6d41\u4f53\u667a\u529b\u7684\u8fc1\u79fb\u3002\u53ef\u9760\u7684\u662f\uff1a\u4f60\u5728 n-back \u53ca\u4e0e\u4e4b\u5bc6\u5207\u76f8\u5173\u7684\u4efb\u52a1\u4e0a\u4f1a\u7a33\u5b9a\u8fdb\u6b65\u3002\u628a\u201c\u63d0\u5347\u667a\u5546\u201d\u5f53\u4f5c\u672a\u7ecf\u8bc1\u5b9e\u5373\u53ef\u3002",rec:"\u4e3a\u4e13\u6ce8\u548c\u66f4\u65b0\u80fd\u529b\u800c\u7ec3\u5b83\uff0c\u4e3a\u6253\u7834\u81ea\u5df1 N \u503c\u7eaa\u5f55\u7684\u6210\u5c31\u611f\u800c\u7ec3\u5b83\u2014\u2014\u800c\u4e0d\u662f\u51b2\u7740\u201c\u667a\u5546\u66f4\u9ad8\u201d\u7684\u627f\u8bfa\u3002\u8ba9\u5b83\u4fdd\u6301\u81ea\u9002\u5e94\uff0c\u5e76\u5728\u75b2\u52b3\u6bc1\u6389\u4f60\u7684\u51c6\u786e\u7387\u4e4b\u524d\u5c31\u505c\u4e0b\u3002",faq:[["N-back \u80fd\u63d0\u5347\u667a\u5546\u5417\uff1f","\u90a3\u9879\u8457\u540d\u7684 2008 \u5e74\u7814\u7a76\u8bf4\u6709\u53ef\u80fd\uff1b\u540e\u6765\u7684\u91cd\u590d\u5b9e\u9a8c\u5927\u591a\u672a\u80fd\u8bc1\u5b9e\u3002\u7a33\u59a5\u7684\u8bf4\u6cd5\u662f\uff1a\u4f60\u4f1a\u66f4\u64c5\u957f n-back \u548c\u5de5\u4f5c\u8bb0\u5fc6\u7c7b\u4efb\u52a1\u3002"],["\u5355\u91cd\u8fd8\u662f\u53cc\u91cd n-back\uff1f","\u4ece\u5355\u91cd\u5f00\u59cb\u3002\u53cc\u91cd\uff08\u4f4d\u7f6e + \u58f0\u97f3\uff09\u66f4\u96be\uff0c\u4e5f\u6b63\u662f\u6700\u521d\u90a3\u4e9b\u8bad\u7ec3\u7814\u7a76\u6240\u91c7\u7528\u7684\u7248\u672c\u3002"],["\u591a\u4e45\u624d\u80fd\u89c1\u5230\u8fdb\u6b65\uff1f","\u4efb\u52a1\u672c\u8eab\u7684\u8fdb\u6b65\u901a\u5e38\u51e0\u5929\u5185\u5c31\u4f1a\u663e\u73b0\uff1b\u81f3\u4e8e\u4efb\u4f55\u66f4\u5e7f\u6cdb\u7684\u8fc1\u79fb\uff0c\u82e5\u771f\u4f1a\u53d1\u751f\uff0c\u4e5f\u9700\u8981\u6570\u5468\u7684\u6bcf\u65e5\u7ec3\u4e60\u3002"]],variants:"\u5355\u91cd n-back\uff08\u5355\u4e00\u523a\u6fc0\u6d41\uff09\uff1b\u53cc\u91cd n-back\uff08\u89c6\u89c9 + \u542c\u89c9\uff09\uff1b\u4ee5\u53ca\u4f4d\u7f6e\u3001\u5b57\u6bcd\u3001\u989c\u8272\u6216\u58f0\u97f3\u7b49\u53d8\u4f53\u3002\u96be\u5ea6\u901a\u8fc7\u63d0\u9ad8 N \u6765\u9012\u589e\u3002"}},"number-bonds":{ru:{about:"\xab\u0427\u0438\u0441\u043b\u043e\u0432\u044b\u0435 \u0441\u0432\u044f\u0437\u043a\u0438\xbb \u2014 \u044d\u0442\u043e \u043a\u043e\u0440\u043e\u0442\u043a\u0430\u044f \u0430\u0440\u0438\u0444\u043c\u0435\u0442\u0438\u0447\u0435\u0441\u043a\u0430\u044f \u0440\u0430\u0437\u043c\u0438\u043d\u043a\u0430 \u043d\u0430 \u043f\u0430\u0440\u044b \u0447\u0438\u0441\u0435\u043b, \u0434\u0430\u044e\u0449\u0438\u0445 \u0432 \u0441\u0443\u043c\u043c\u0435 \u0437\u0430\u0434\u0430\u043d\u043d\u043e\u0435 \u0446\u0435\u043b\u043e\u0435. \u0412\u0430\u043c \u043f\u043e\u043a\u0430\u0437\u044b\u0432\u0430\u044e\u0442 \u0446\u0435\u043b\u044c \u0438 \u043e\u0434\u043d\u043e \u0447\u0438\u0441\u043b\u043e, \u0430 \u0432\u044b \u043a\u0430\u043a \u043c\u043e\u0436\u043d\u043e \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u043d\u0430\u0437\u044b\u0432\u0430\u0435\u0442\u0435 \u0435\u0433\u043e \u043d\u0435\u0434\u043e\u0441\u0442\u0430\u044e\u0449\u0443\u044e \u043f\u0430\u0440\u0443 \u2014 \u0440\u0430\u0443\u043d\u0434 \u0437\u0430 \u0440\u0430\u0443\u043d\u0434\u043e\u043c, \u043f\u043e\u043a\u0430 \u0441\u043e\u0447\u0435\u0442\u0430\u043d\u0438\u044f \u043d\u0435 \u043d\u0430\u0447\u043d\u0443\u0442 \u0432\u0441\u043f\u043b\u044b\u0432\u0430\u0442\u044c \u0441\u0430\u043c\u0438.",benefit:"\u0422\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u0431\u0435\u0433\u043b\u043e\u0441\u0442\u044c \u0441\u0447\u0451\u0442\u0430 \u2014 \u043c\u0433\u043d\u043e\u0432\u0435\u043d\u043d\u043e\u0435, \u0431\u0435\u0437 \u0443\u0441\u0438\u043b\u0438\u0439, \u043f\u0440\u0438\u043f\u043e\u043c\u0438\u043d\u0430\u043d\u0438\u0435 \u043f\u0440\u043e\u0441\u0442\u044b\u0445 \u0447\u0438\u0441\u043b\u043e\u0432\u044b\u0445 \u0444\u0430\u043a\u0442\u043e\u0432. \u041a\u043e\u0433\u0434\u0430 \u043e\u0442\u0432\u0435\u0442 \u0432\u0441\u043f\u043b\u044b\u0432\u0430\u0435\u0442 \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u0438, \u0432 \u0431\u043e\u043b\u044c\u0448\u0438\u0445 \u0432\u044b\u0447\u0438\u0441\u043b\u0435\u043d\u0438\u044f\u0445 \u043e\u0441\u0432\u043e\u0431\u043e\u0436\u0434\u0430\u0435\u0442\u0441\u044f \u043e\u043f\u0435\u0440\u0430\u0442\u0438\u0432\u043d\u0430\u044f \u043f\u0430\u043c\u044f\u0442\u044c: \u043c\u0430\u043b\u0435\u043d\u044c\u043a\u0438\u0435 \u0441\u0443\u043c\u043c\u044b \u0432\u044b \u0443\u0436\u0435 \u043d\u0435 \u0441\u0447\u0438\u0442\u0430\u0435\u0442\u0435, \u0430 \u043f\u0440\u043e\u0441\u0442\u043e \u0432\u0441\u043f\u043e\u043c\u0438\u043d\u0430\u0435\u0442\u0435.",history:"\u0418\u0434\u0435\u044f \xab\u0447\u0430\u0441\u0442\u044c \u2014 \u0447\u0430\u0441\u0442\u044c \u2014 \u0446\u0435\u043b\u043e\u0435\xbb, \u043b\u0435\u0436\u0430\u0449\u0430\u044f \u0432 \u043e\u0441\u043d\u043e\u0432\u0435 \u0447\u0438\u0441\u043b\u043e\u0432\u044b\u0445 \u0441\u0432\u044f\u0437\u043e\u043a, \u0440\u0430\u0437\u043e\u0448\u043b\u0430\u0441\u044c \u043f\u043e \u043d\u0430\u0447\u0430\u043b\u044c\u043d\u043e\u043c\u0443 \u043e\u0431\u0443\u0447\u0435\u043d\u0438\u044e \u043c\u0430\u0442\u0435\u043c\u0430\u0442\u0438\u043a\u0435 \u0432 \u0415\u0432\u0440\u043e\u043f\u0435 \u0432 \u0441\u0435\u0440\u0435\u0434\u0438\u043d\u0435 XX \u0432\u0435\u043a\u0430 \u2014 \u0432\u043c\u0435\u0441\u0442\u0435 \u0441 \u043d\u0430\u0433\u043b\u044f\u0434\u043d\u044b\u043c\u0438 \u043c\u0435\u0442\u043e\u0434\u0430\u043c\u0438 \u041a\u0430\u0442\u0440\u0438\u043d \u0428\u0442\u0435\u0440\u043d \u0438 \u0416\u043e\u0440\u0436\u0430 \u041a\u044e\u0438\u0437\u0435\u043d\u0435\u0440\u0430. \u0410\u043d\u0433\u043b\u0438\u0439\u0441\u043a\u0438\u0439 \u0442\u0435\u0440\u043c\u0438\u043d \xabnumber bonds\xbb \u0441\u0442\u0430\u043b \u0448\u0438\u0440\u043e\u043a\u043e \u0438\u0437\u0432\u0435\u0441\u0442\u0435\u043d \u0431\u043b\u0430\u0433\u043e\u0434\u0430\u0440\u044f \u0441\u0438\u043d\u0433\u0430\u043f\u0443\u0440\u0441\u043a\u043e\u0439 \u043c\u0430\u0442\u0435\u043c\u0430\u0442\u0438\u043a\u0435, \u0447\u044c\u044e \u0448\u043a\u043e\u043b\u044c\u043d\u0443\u044e \u043f\u0440\u043e\u0433\u0440\u0430\u043c\u043c\u0443 \u0440\u0435\u0444\u043e\u0440\u043c\u0438\u0440\u043e\u0432\u0430\u043b\u0438 \u0432 1980-\u0445 \u0438 \u043f\u043e\u0437\u0436\u0435 \u0432\u044b\u0432\u0435\u0437\u043b\u0438 \u043f\u043e \u0432\u0441\u0435\u043c\u0443 \u043c\u0438\u0440\u0443.",creator:"\u0415\u0434\u0438\u043d\u043e\u0433\u043e \u0430\u0432\u0442\u043e\u0440\u0430 \u043d\u0435\u0442. \u0427\u0438\u0441\u043b\u043e\u0432\u044b\u0435 \u0441\u0432\u044f\u0437\u043a\u0438 \u2014 \u044d\u0442\u043e \u043e\u0431\u0449\u0438\u0439 \u043e\u0431\u0443\u0447\u0430\u044e\u0449\u0438\u0439 \u043f\u0440\u0438\u0451\u043c \u0438\u0437 \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u0438 \u043d\u0430\u0447\u0430\u043b\u044c\u043d\u043e\u0439 \u043c\u0430\u0442\u0435\u043c\u0430\u0442\u0438\u043a\u0438; \u043a\u043e\u043d\u043a\u0440\u0435\u0442\u043d\u0443\u044e \u0441\u0445\u0435\u043c\u0443 \xab\u0447\u0430\u0441\u0442\u044c \u2014 \u0447\u0430\u0441\u0442\u044c \u2014 \u0446\u0435\u043b\u043e\u0435\xbb \u0438 \u0441\u0430\u043c\u043e \u043d\u0430\u0437\u0432\u0430\u043d\u0438\u0435 \u043f\u043e\u043f\u0443\u043b\u044f\u0440\u0438\u0437\u0438\u0440\u043e\u0432\u0430\u043b\u0430 \u0443\u0447\u0435\u0431\u043d\u0430\u044f \u043f\u0440\u043e\u0433\u0440\u0430\u043c\u043c\u0430 \u041c\u0438\u043d\u0438\u0441\u0442\u0435\u0440\u0441\u0442\u0432\u0430 \u043e\u0431\u0440\u0430\u0437\u043e\u0432\u0430\u043d\u0438\u044f \u0421\u0438\u043d\u0433\u0430\u043f\u0443\u0440\u0430 (\u043e\u043d\u0430 \u0441\u043a\u043b\u0430\u0434\u044b\u0432\u0430\u043b\u0430\u0441\u044c \u0432 1980-\u0445 \u043d\u0430 \u0431\u043e\u043b\u0435\u0435 \u0440\u0430\u043d\u043d\u0438\u0445 \u0438\u0434\u0435\u044f\u0445 \u0414\u0436\u0435\u0440\u043e\u043c\u0430 \u0411\u0440\u0443\u043d\u0435\u0440\u0430 \u043e \u043f\u0435\u0440\u0435\u0445\u043e\u0434\u0435 \xab\u043a\u043e\u043d\u043a\u0440\u0435\u0442\u043d\u043e\u0435 \u2014 \u043d\u0430\u0433\u043b\u044f\u0434\u043d\u043e\u0435 \u2014 \u0430\u0431\u0441\u0442\u0440\u0430\u043a\u0442\u043d\u043e\u0435\xbb).",methods:"\u0411\u0435\u0440\u0438\u0442\u0435 \u043f\u043e \u043e\u0434\u043d\u043e\u0439 \u0446\u0435\u043b\u0438 \u0437\u0430 \u0440\u0430\u0437 \u0438 \u0434\u043e\u0432\u043e\u0434\u0438\u0442\u0435 \u0435\u0451 \u043f\u0430\u0440\u044b \u0434\u043e \u043c\u0433\u043d\u043e\u0432\u0435\u043d\u043d\u043e\u0433\u043e \u043e\u0442\u0432\u0435\u0442\u0430, \u0437\u0430\u0442\u0435\u043c \u043f\u0435\u0440\u0435\u0445\u043e\u0434\u0438\u0442\u0435 \u043a \u0441\u043b\u0435\u0434\u0443\u044e\u0449\u0435\u0439 \u0438 \u0432\u0440\u0435\u043c\u044f \u043e\u0442 \u0432\u0440\u0435\u043c\u0435\u043d\u0438 \u043f\u0435\u0440\u0435\u043c\u0435\u0448\u0438\u0432\u0430\u0439\u0442\u0435 \u0446\u0435\u043b\u0438. \u0421\u0442\u0440\u0435\u043c\u0438\u0442\u0435\u0441\u044c \u0438\u043c\u0435\u043d\u043d\u043e \u0432\u0441\u043f\u043e\u043c\u0438\u043d\u0430\u0442\u044c, \u0430 \u043d\u0435 \u0441\u0447\u0438\u0442\u0430\u0442\u044c \u043d\u0430 \u043f\u0430\u043b\u044c\u0446\u0430\u0445, \u0438 \u0434\u0435\u0440\u0436\u0438\u0442\u0435 \u0447\u0443\u0442\u044c \u043d\u0435\u043a\u043e\u043c\u0444\u043e\u0440\u0442\u043d\u044b\u0439 \u0442\u0435\u043c\u043f \u2014 \u0442\u0430\u043a \u0432\u044b \u0434\u043e\u0441\u0442\u0430\u0451\u0442\u0435 \u043e\u0442\u0432\u0435\u0442 \u0438\u0437 \u043f\u0430\u043c\u044f\u0442\u0438, \u0430 \u043d\u0435 \u0432\u044b\u0432\u043e\u0434\u0438\u0442\u0435 \u0435\u0433\u043e \u0437\u0430\u043d\u043e\u0432\u043e.",duration:"\u041a\u043e\u0440\u043e\u0442\u043a\u043e \u0438 \u0447\u0430\u0441\u0442\u043e \u043b\u0443\u0447\u0448\u0435, \u0447\u0435\u043c \u0434\u043e\u043b\u0433\u043e \u0438 \u0440\u0435\u0434\u043a\u043e: 5\u201310 \u043c\u0438\u043d\u0443\u0442 \u0432 \u0434\u0435\u043d\u044c \u0432\u043f\u043e\u043b\u043d\u0435 \u0434\u043e\u0441\u0442\u0430\u0442\u043e\u0447\u043d\u043e. \u041d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u043c\u0438\u043d\u0443\u0442 \u0435\u0436\u0435\u0434\u043d\u0435\u0432\u043d\u043e \u043f\u0430\u0440\u0443 \u043d\u0435\u0434\u0435\u043b\u044c \u0434\u0430\u044e\u0442 \u0434\u043b\u044f \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0437\u043c\u0430 \u0431\u043e\u043b\u044c\u0448\u0435, \u0447\u0435\u043c \u043e\u0434\u043d\u043e \u0434\u043b\u0438\u043d\u043d\u043e\u0435 \u0437\u0430\u043d\u044f\u0442\u0438\u0435 \u0440\u0430\u0437 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e.",research:"\u041d\u0430\u0434\u0451\u0436\u043d\u043e \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043d\u043e \u0440\u043e\u0432\u043d\u043e \u0442\u043e, \u043d\u0430 \u0447\u0442\u043e \u043d\u0430\u0446\u0435\u043b\u0435\u043d\u0430 \u0440\u0430\u0437\u043c\u0438\u043d\u043a\u0430: \u0432\u044b \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u0438 \u0442\u043e\u0447\u043d\u0435\u0435 \u0432\u0441\u043f\u043e\u043c\u0438\u043d\u0430\u0435\u0442\u0435 \u0442\u0435 \u0447\u0438\u0441\u043b\u043e\u0432\u044b\u0435 \u0444\u0430\u043a\u0442\u044b, \u0447\u0442\u043e \u043e\u0442\u0440\u0430\u0431\u0430\u0442\u044b\u0432\u0430\u043b\u0438, \u0430 \u044d\u0442\u0430 \u0431\u0435\u0433\u043b\u043e\u0441\u0442\u044c \u043e\u0441\u0432\u043e\u0431\u043e\u0436\u0434\u0430\u0435\u0442 \u043e\u043f\u0435\u0440\u0430\u0442\u0438\u0432\u043d\u0443\u044e \u043f\u0430\u043c\u044f\u0442\u044c \u043f\u043e\u0434 \u0431\u043e\u043b\u0435\u0435 \u0442\u0440\u0443\u0434\u043d\u044b\u0435 \u0437\u0430\u0434\u0430\u0447\u0438 \u0438 \u0441\u0432\u044f\u0437\u0430\u043d\u0430 \u0441 \u0434\u0430\u043b\u044c\u043d\u0435\u0439\u0448\u0438\u043c\u0438 \u0443\u0441\u043f\u0435\u0445\u0430\u043c\u0438 \u0432 \u043c\u0430\u0442\u0435\u043c\u0430\u0442\u0438\u043a\u0435. \u0423\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043d\u0438\u044f, \u0447\u0442\u043e \u0442\u0430\u043a\u0430\u044f \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u0430 \u043f\u043e\u0434\u043d\u0438\u043c\u0430\u0435\u0442 \u043e\u0431\u0449\u0438\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0438\u043b\u0438 \u0434\u0430\u0451\u0442 \u0448\u0438\u0440\u043e\u043a\u0438\u0439 \u043f\u0435\u0440\u0435\u043d\u043e\u0441 \u043d\u0430 \u043d\u0435 \u0441\u0432\u044f\u0437\u0430\u043d\u043d\u044b\u0435 \u043d\u0430\u0432\u044b\u043a\u0438, \u0441\u043b\u0430\u0431\u044b \u0438 \u043f\u043e \u0431\u043e\u043b\u044c\u0448\u0435\u0439 \u0447\u0430\u0441\u0442\u0438 \u043d\u0435 \u0434\u043e\u043a\u0430\u0437\u0430\u043d\u044b; \u0431\u043b\u0438\u0437\u043a\u0438\u0435 \u043f\u043e \u0434\u0443\u0445\u0443 \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0438 \u0440\u0430\u0431\u043e\u0447\u0435\u0439 \u043f\u0430\u043c\u044f\u0442\u0438 \u0440\u0430\u0437 \u0437\u0430 \u0440\u0430\u0437\u043e\u043c \u043d\u0435 \u0434\u0430\u0432\u0430\u043b\u0438 \u0441\u0442\u043e\u0439\u043a\u043e\u0433\u043e \xab\u0434\u0430\u043b\u044c\u043d\u0435\u0433\u043e\xbb \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0430 \u2014 \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u043a \u0433\u0440\u043e\u043c\u043a\u0438\u043c \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f\u043c \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u0435\u0441\u044c \u0441\u0434\u0435\u0440\u0436\u0430\u043d\u043d\u043e.",rec:"\u041d\u0430\u0447\u043d\u0438\u0442\u0435 \u0441\u043e \u0441\u0432\u044f\u0437\u043e\u043a \u0434\u043e 10, \u0434\u043e\u0432\u0435\u0434\u0438\u0442\u0435 \u0438\u0445 \u0434\u043e \u043f\u043e-\u043d\u0430\u0441\u0442\u043e\u044f\u0449\u0435\u043c\u0443 \u043c\u0433\u043d\u043e\u0432\u0435\u043d\u043d\u043e\u0433\u043e \u043e\u0442\u0432\u0435\u0442\u0430 \u0438 \u043b\u0438\u0448\u044c \u043f\u043e\u0442\u043e\u043c \u043f\u0435\u0440\u0435\u0445\u043e\u0434\u0438\u0442\u0435 \u043a \u0441\u0432\u044f\u0437\u043a\u0430\u043c \u0434\u043e 20 \u0438 \u0434\u043e 100 \u2014 \u043a\u043e\u0433\u0434\u0430 \u043c\u0435\u043d\u044c\u0448\u0438\u0435 \u0434\u0430\u044e\u0442\u0441\u044f \u0441\u043e\u0432\u0441\u0435\u043c \u043b\u0435\u0433\u043a\u043e.",faq:[["\u0427\u0442\u043e \u0442\u0430\u043a\u043e\u0435 \u0447\u0438\u0441\u043b\u043e\u0432\u0430\u044f \u0441\u0432\u044f\u0437\u043a\u0430?","\u042d\u0442\u043e \u043f\u0430\u0440\u0430 \u0447\u0438\u0441\u0435\u043b, \u0434\u0430\u044e\u0449\u0438\u0445 \u0432 \u0441\u0443\u043c\u043c\u0435 \u043e\u043f\u0440\u0435\u0434\u0435\u043b\u0451\u043d\u043d\u043e\u0435 \u0446\u0435\u043b\u043e\u0435: \u043d\u0430\u043f\u0440\u0438\u043c\u0435\u0440, 3 \u0438 7 \u2014 \u0441\u0432\u044f\u0437\u043a\u0430 \u0434\u043b\u044f 10, \u0438 4 \u0441 6 \u0442\u043e\u0436\u0435. \u0421\u043c\u044b\u0441\u043b \u0432 \u0442\u043e\u043c, \u0447\u0442\u043e\u0431\u044b \u0437\u043d\u0430\u0442\u044c \u0442\u0430\u043a\u0438\u0435 \u043f\u0430\u0440\u044b \u043d\u0430\u0438\u0437\u0443\u0441\u0442\u044c."],["\u0421\u0442\u0430\u043d\u0443 \u043b\u0438 \u044f \u043e\u0442 \u044d\u0442\u043e\u0433\u043e \u043b\u0443\u0447\u0448\u0435 \u0432 \u043c\u0430\u0442\u0435\u043c\u0430\u0442\u0438\u043a\u0435 \u0432\u043e\u043e\u0431\u0449\u0435?","\u0411\u0430\u0437\u043e\u0432\u044b\u0435 \u0444\u0430\u043a\u0442\u044b \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043b\u044c\u043d\u043e \u0441\u0442\u0430\u043d\u043e\u0432\u044f\u0442\u0441\u044f \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u0438\u043c\u0438, \u0438 \u044d\u0442\u043e \u0443\u0431\u0438\u0440\u0430\u0435\u0442 \u0443\u0437\u043a\u043e\u0435 \u043c\u0435\u0441\u0442\u043e \u0432 \u0431\u043e\u043b\u044c\u0448\u0438\u0445 \u0432\u044b\u0447\u0438\u0441\u043b\u0435\u043d\u0438\u044f\u0445. \u041d\u043e \u044d\u0442\u043e \u043d\u0435 \u043f\u0443\u0442\u044c \u043a \u0440\u043e\u0441\u0442\u0443 \u043e\u0431\u0449\u0435\u0433\u043e \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442\u0430 \u2014 \u0448\u0438\u0440\u043e\u043a\u0438\u0435 \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f \xab\u043f\u0440\u043e\u043a\u0430\u0447\u0430\u0442\u044c \u043c\u043e\u0437\u0433\xbb \u043f\u043e\u0434\u043e\u0431\u043d\u044b\u043c\u0438 \u0440\u0430\u0437\u043c\u0438\u043d\u043a\u0430\u043c\u0438 \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043d\u044b \u043f\u043b\u043e\u0445\u043e."],["\u042d\u0442\u043e \u0442\u043e\u043b\u044c\u043a\u043e \u0434\u043b\u044f \u0434\u0435\u0442\u0435\u0439?","\u041d\u0435\u0442. \u041f\u0440\u0438\u0451\u043c \u043f\u0440\u043e\u0445\u043e\u0434\u044f\u0442 \u0432 \u043d\u0430\u0447\u0430\u043b\u044c\u043d\u043e\u0439 \u0448\u043a\u043e\u043b\u0435, \u043d\u043e \u0440\u0430\u0437\u043c\u0438\u043d\u043a\u0430 \u043f\u043e\u043b\u0435\u0437\u043d\u0430 \u0432 \u043b\u044e\u0431\u043e\u043c \u0432\u043e\u0437\u0440\u0430\u0441\u0442\u0435 \u2014 \u0447\u0442\u043e\u0431\u044b \u0440\u0430\u0437\u043e\u0433\u043d\u0430\u0442\u044c \u0443\u0441\u0442\u043d\u044b\u0439 \u0441\u0447\u0451\u0442 \u0438 \u0441\u0442\u0440\u044f\u0445\u043d\u0443\u0442\u044c \u0440\u0436\u0430\u0432\u0447\u0438\u043d\u0443."]],variants:"\u041e\u0431\u044b\u0447\u043d\u044b\u0435 \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u044b \u043c\u0435\u043d\u044f\u044e\u0442 \u0446\u0435\u043b\u044c (\u0441\u0432\u044f\u0437\u043a\u0438 \u0434\u043e 10, 20, 50, 100), \u0437\u0430\u043c\u0435\u043d\u044f\u044e\u0442 \u0441\u043b\u043e\u0436\u0435\u043d\u0438\u0435 \u043d\u0430 \u043f\u0430\u0440\u043d\u044b\u0439 \u0444\u0430\u043a\u0442 \u0432\u044b\u0447\u0438\u0442\u0430\u043d\u0438\u044f (\u0434\u0430\u043d\u043e \u0446\u0435\u043b\u043e\u0435 \u0438 \u043e\u0434\u043d\u0430 \u0447\u0430\u0441\u0442\u044c \u2014 \u043d\u0430\u0439\u0434\u0438 \u0432\u0442\u043e\u0440\u0443\u044e), \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u044e\u0442 \u0442\u0440\u0438 \u0447\u0430\u0441\u0442\u0438 \u0432\u043c\u0435\u0441\u0442\u043e \u0434\u0432\u0443\u0445 \u0438\u043b\u0438 \u0434\u043e\u0431\u0430\u0432\u043b\u044f\u044e\u0442 \u0434\u0440\u043e\u0431\u0438 \u0438 \u0434\u0435\u0441\u044f\u0442\u0438\u0447\u043d\u044b\u0435 \u0434\u043b\u044f \u0443\u0441\u043b\u043e\u0436\u043d\u0435\u043d\u0438\u044f."},en:{about:"Number Bonds is a quick arithmetic drill built around pairs of numbers that add up to a target whole. You are shown a target and a number, and your job is to tap or type its missing partner as fast as you can, round after round, so the pairings become automatic.",benefit:"It trains arithmetic fluency, the fast and effortless recall of basic number facts. As recall becomes automatic, it frees up working memory during larger calculations, because you stop computing small sums and start simply remembering them.",history:"The part-part-whole idea behind number bonds spread through European primary-maths teaching in the mid-20th century, alongside hands-on methods like those of Catherine Stern and Georges Cuisenaire. The English term \"number bonds\" became widely familiar through Singapore maths, whose national curriculum was reformed in the 1980s and later exported worldwide.",creator:"There is no single inventor. Number bonds are a generic teaching concept from the primary-mathematics tradition; the specific part-part-whole diagram and the name were popularised by Singapore's Ministry of Education curriculum (built up through the 1980s on Jerome Bruner's earlier concrete-pictorial-abstract ideas).",methods:"Train one target at a time until the pairs for it are instant, then move on, and circle back to mix targets together. Aim for recall, not counting on your fingers, and push for a slightly uncomfortable pace so you are retrieving answers rather than working them out.",duration:"Short and frequent beats long and rare: 5 to 10 minutes a day is plenty. A few minutes daily for a couple of weeks does more for automaticity than one long weekly session.",research:"Evidence is solid for exactly what the drill targets \u2014 you get faster and more accurate at recalling the number facts you practise, and that fluency frees working memory for harder problems and predicts later maths achievement. Claims that this kind of practice raises general intelligence or produces broad transfer to unrelated skills are weak and largely unproven; related working-memory training has repeatedly failed to deliver lasting far-transfer, so treat any grand promises with caution.",rec:"Start with bonds to 10, get them genuinely instant, then step up to bonds to 20 and 100 only once the smaller ones feel effortless.",faq:[["What exactly is a number bond?","It is a pair of numbers that add up to a particular whole \u2014 for example 3 and 7 are a number bond for 10, and so are 4 and 6. Knowing them by heart is the point."],["Will this make me better at maths in general?","It reliably makes the basic facts automatic, which removes a bottleneck in bigger calculations. It is not a shortcut to general intelligence, and the broad 'brain-boosting' claims around such drills are not well supported."],["Is this only for children?","No. The concept is taught to children, but the drill is useful at any age for sharpening mental-arithmetic speed and shaking off rust."]],variants:"Common variations change the target (bonds to 10, 20, 50, 100), swap addition for the matching subtraction fact (given the whole and one part, find the other), use three parts instead of two, or add decimals and fractions for an extra challenge."},es:{about:"Number Bonds es un ejercicio r\xe1pido de aritm\xe9tica construido en torno a parejas de n\xfameros que suman un total objetivo. Se te muestra un objetivo y un n\xfamero, y tu tarea es tocar o teclear su pareja que falta lo m\xe1s r\xe1pido posible, ronda tras ronda, hasta que los emparejamientos se vuelven autom\xe1ticos.",benefit:"Entrena la fluidez aritm\xe9tica, la recuperaci\xf3n r\xe1pida y sin esfuerzo de los hechos num\xe9ricos b\xe1sicos. A medida que la recuperaci\xf3n se automatiza, libera memoria de trabajo durante los c\xe1lculos m\xe1s grandes, porque dejas de calcular sumas peque\xf1as y empiezas simplemente a recordarlas.",history:"La idea de parte-parte-todo que hay detr\xe1s de los number bonds se extendi\xf3 por la ense\xf1anza europea de matem\xe1ticas de primaria a mediados del siglo XX, junto con m\xe9todos manipulativos como los de Catherine Stern y Georges Cuisenaire. El t\xe9rmino ingl\xe9s \"number bonds\" se hizo ampliamente conocido a trav\xe9s del m\xe9todo de matem\xe1ticas de Singapur, cuyo plan de estudios nacional se reform\xf3 en los a\xf1os 80 y m\xe1s tarde se export\xf3 por todo el mundo.",creator:"No hay un \xfanico inventor. Los number bonds son un concepto pedag\xf3gico gen\xe9rico de la tradici\xf3n de matem\xe1ticas de primaria; el diagrama concreto de parte-parte-todo y el nombre fueron popularizados por el plan de estudios del Ministerio de Educaci\xf3n de Singapur (construido a lo largo de los a\xf1os 80 sobre las ideas previas de concreto-pict\xf3rico-abstracto de Jerome Bruner).",methods:"Entrena un objetivo cada vez hasta que sus parejas sean instant\xe1neas, luego pasa al siguiente y vuelve despu\xe9s para mezclar objetivos. Busca la recuperaci\xf3n, no contar con los dedos, y fu\xe9rzate a un ritmo algo inc\xf3modo para estar recordando respuestas en lugar de calcularlas.",duration:"Lo corto y frecuente gana a lo largo y espor\xe1dico: de 5 a 10 minutos al d\xeda bastan. Unos minutos a diario durante un par de semanas hacen m\xe1s por la automatizaci\xf3n que una \xfanica sesi\xf3n larga semanal.",research:"La evidencia es s\xf3lida para justo lo que el ejercicio persigue: mejoras en velocidad y precisi\xf3n al recuperar los hechos num\xe9ricos que practicas, y esa fluidez libera memoria de trabajo para problemas m\xe1s dif\xedciles y predice el rendimiento matem\xe1tico posterior. Las afirmaciones de que este tipo de pr\xe1ctica eleva la inteligencia general o produce una transferencia amplia a habilidades no relacionadas son d\xe9biles y en gran medida sin demostrar; el entrenamiento de memoria de trabajo af\xedn ha fallado repetidamente en lograr una transferencia lejana duradera, as\xed que toma con cautela cualquier gran promesa.",rec:"Empieza con las parejas que suman 10, convi\xe9rtelas en algo genuinamente instant\xe1neo, y solo entonces sube a las parejas que suman 20 y 100 cuando las m\xe1s peque\xf1as te resulten naturales.",faq:[["\xbfQu\xe9 es exactamente un number bond?","Es una pareja de n\xfameros que suman un total concreto; por ejemplo, 3 y 7 son un number bond del 10, y tambi\xe9n lo son 4 y 6. La gracia est\xe1 en sab\xe9rselos de memoria."],["\xbfEsto me har\xe1 mejor en matem\xe1ticas en general?","Automatiza de forma fiable los hechos b\xe1sicos, lo que elimina un cuello de botella en los c\xe1lculos m\xe1s grandes. No es un atajo a la inteligencia general, y las afirmaciones amplias de 'potenciar el cerebro' en torno a estos ejercicios no est\xe1n bien respaldadas."],["\xbfEsto es solo para ni\xf1os?","No. El concepto se ense\xf1a a los ni\xf1os, pero el ejercicio es \xfatil a cualquier edad para afinar la velocidad de c\xe1lculo mental y quitarse el \xf3xido."]],variants:"Las variantes habituales cambian el objetivo (parejas que suman 10, 20, 50, 100), sustituyen la suma por la resta correspondiente (dado el todo y una parte, encuentra la otra), usan tres partes en lugar de dos, o a\xf1aden decimales y fracciones como reto extra."},de:{about:"Number Bonds ist eine schnelle Rechen\xfcbung rund um Zahlenpaare, die zusammen ein Zielganzes ergeben. Dir werden ein Ziel und eine Zahl gezeigt, und deine Aufgabe ist es, den fehlenden Partner so schnell wie m\xf6glich anzutippen oder einzutippen, Runde um Runde, bis die Paarungen in Fleisch und Blut \xfcbergehen.",benefit:"Sie trainiert Rechensicherheit, das schnelle und m\xfchelose Abrufen grundlegender Zahlenfakten. Sobald der Abruf automatisch wird, entlastet er das Arbeitsged\xe4chtnis bei gr\xf6\xdferen Rechnungen, weil du aufh\xf6rst, kleine Summen auszurechnen, und anf\xe4ngst, sie einfach zu erinnern.",history:"Die Teil-Teil-Ganzes-Idee hinter den Zahlenpaaren verbreitete sich Mitte des 20. Jahrhunderts im europ\xe4ischen Grundschulrechnen, zusammen mit handlungsorientierten Methoden wie denen von Catherine Stern und Georges Cuisenaire. Der englische Begriff 'number bonds' wurde durch die Singapur-Mathematik weithin bekannt, deren nationaler Lehrplan in den 1980er Jahren reformiert und sp\xe4ter weltweit exportiert wurde.",creator:"Es gibt keinen einzelnen Erfinder. Zahlenpaare sind ein allgemeines Lehrkonzept aus der Grundschulmathematik-Tradition; das spezielle Teil-Teil-Ganzes-Diagramm und der Name wurden durch den Lehrplan des Bildungsministeriums von Singapur popul\xe4r gemacht (\xfcber die 1980er Jahre hinweg aufgebaut auf Jerome Bruners fr\xfcheren konkret-bildhaft-abstrakten Ideen).",methods:"Trainiere ein Ziel nach dem anderen, bis dessen Paare sofort sitzen, geh dann weiter und kehre sp\xe4ter zur\xfcck, um die Ziele zu mischen. Strebe Abruf an, nicht das Abz\xe4hlen an den Fingern, und treibe ein leicht unbequemes Tempo voran, sodass du Antworten abrufst statt sie auszurechnen.",duration:"Kurz und h\xe4ufig schl\xe4gt lang und selten: 5 bis 10 Minuten am Tag reichen v\xf6llig. Ein paar Minuten t\xe4glich \xfcber ein paar Wochen bringen f\xfcr die Automatisierung mehr als eine lange w\xf6chentliche Sitzung.",research:"Die Evidenz ist solide f\xfcr genau das, worauf die \xdcbung zielt \u2014 du wirst schneller und genauer beim Abrufen der ge\xfcbten Zahlenfakten, und diese Sicherheit entlastet das Arbeitsged\xe4chtnis f\xfcr schwierigere Aufgaben und sagt sp\xe4tere Mathematikleistungen voraus. Behauptungen, dass diese Art von \xdcbung die allgemeine Intelligenz hebt oder einen breiten \xdcbertrag auf unverwandte Fertigkeiten erzeugt, sind schwach und weitgehend unbewiesen; verwandtes Arbeitsged\xe4chtnistraining hat wiederholt keinen dauerhaften Ferntransfer geliefert, also begegne jedem gro\xdfen Versprechen mit Vorsicht.",rec:"Beginne mit den Paaren zu 10, lass sie wirklich sofort sitzen, und steige erst zu den Paaren zu 20 und 100 auf, wenn die kleineren sich m\xfchelos anf\xfchlen.",faq:[["Was genau ist ein Zahlenpaar (number bond)?","Es ist ein Paar von Zahlen, die zusammen ein bestimmtes Ganzes ergeben \u2014 zum Beispiel sind 3 und 7 ein Zahlenpaar zu 10, und 4 und 6 ebenso. Sie auswendig zu kennen, ist der Sinn der Sache."],["Macht mich das insgesamt besser in Mathe?","Es macht die Grundfakten zuverl\xe4ssig automatisch, was einen Engpass bei gr\xf6\xdferen Rechnungen beseitigt. Es ist keine Abk\xfcrzung zu allgemeiner Intelligenz, und die breiten 'gehirnst\xe4rkenden' Behauptungen rund um solche \xdcbungen sind nicht gut belegt."],["Ist das nur etwas f\xfcr Kinder?","Nein. Das Konzept wird Kindern beigebracht, aber die \xdcbung ist in jedem Alter n\xfctzlich, um die Kopfrechengeschwindigkeit zu sch\xe4rfen und Rost abzusch\xfctteln."]],variants:"\xdcbliche Abwandlungen ver\xe4ndern das Ziel (Paare zu 10, 20, 50, 100), tauschen die Addition gegen den passenden Subtraktionsfakt (gegeben das Ganze und ein Teil, finde das andere), nutzen drei Teile statt zwei oder erg\xe4nzen Dezimalzahlen und Br\xfcche f\xfcr eine zus\xe4tzliche Herausforderung."},pt:{about:"Number Bonds \xe9 um exerc\xedcio r\xe1pido de aritm\xe9tica montado em torno de pares de n\xfameros que somam um total alvo. Voc\xea v\xea um alvo e um n\xfamero, e sua miss\xe3o \xe9 tocar ou digitar o parceiro que falta o mais r\xe1pido poss\xedvel, rodada ap\xf3s rodada, at\xe9 que os pares se tornem autom\xe1ticos.",benefit:"Treina a flu\xeancia aritm\xe9tica, a evoca\xe7\xe3o r\xe1pida e sem esfor\xe7o de fatos num\xe9ricos b\xe1sicos. \xc0 medida que a evoca\xe7\xe3o se torna autom\xe1tica, libera a mem\xf3ria de trabalho durante c\xe1lculos maiores, porque voc\xea deixa de calcular as pequenas somas e passa simplesmente a lembr\xe1-las.",history:"A ideia de parte-parte-todo por tr\xe1s dos number bonds se espalhou pelo ensino europeu de matem\xe1tica nas s\xe9ries iniciais em meados do s\xe9culo XX, ao lado de m\xe9todos pr\xe1ticos como os de Catherine Stern e Georges Cuisenaire. O termo ingl\xeas \"number bonds\" tornou-se amplamente conhecido pela matem\xe1tica de Singapura, cujo curr\xedculo nacional foi reformado nos anos 1980 e mais tarde exportado para o mundo todo.",creator:"N\xe3o h\xe1 um \xfanico inventor. Os number bonds s\xe3o um conceito de ensino gen\xe9rico da tradi\xe7\xe3o da matem\xe1tica das s\xe9ries iniciais; o diagrama espec\xedfico de parte-parte-todo e o nome foram popularizados pelo curr\xedculo do Minist\xe9rio da Educa\xe7\xe3o de Singapura (constru\xeddo ao longo dos anos 1980 sobre as ideias anteriores de concreto-pict\xf3rico-abstrato de Jerome Bruner).",methods:"Treine um alvo de cada vez at\xe9 que os pares dele sejam instant\xe2neos, depois siga em frente, e volte para misturar os alvos. Busque a evoca\xe7\xe3o, n\xe3o a contagem nos dedos, e force um ritmo levemente desconfort\xe1vel para que voc\xea esteja recuperando respostas em vez de calcul\xe1-las.",duration:"Curto e frequente bate longo e raro: 5 a 10 minutos por dia bastam. Alguns minutos di\xe1rios por algumas semanas fazem mais pela automaticidade do que uma \xfanica e longa sess\xe3o semanal.",research:"A evid\xeancia \xe9 s\xf3lida exatamente para o que o exerc\xedcio mira \u2014 voc\xea fica mais r\xe1pido e mais preciso em evocar os fatos num\xe9ricos que pratica, e essa flu\xeancia libera a mem\xf3ria de trabalho para problemas mais dif\xedceis e prev\xea o desempenho posterior em matem\xe1tica. Afirma\xe7\xf5es de que esse tipo de pr\xe1tica eleva a intelig\xeancia geral ou produz transfer\xeancia ampla para habilidades n\xe3o relacionadas s\xe3o fracas e em grande parte n\xe3o comprovadas; o treino de mem\xf3ria de trabalho relacionado falhou repetidamente em entregar transfer\xeancia distante duradoura, ent\xe3o trate qualquer promessa grandiosa com cautela.",rec:"Comece com os pares que somam 10, deixe-os genuinamente instant\xe2neos e s\xf3 ent\xe3o avance para os pares que somam 20 e 100, quando os menores parecerem sem esfor\xe7o.",faq:[["O que \xe9 exatamente um number bond?","\xc9 um par de n\xfameros que soma um determinado todo \u2014 por exemplo, 3 e 7 s\xe3o um number bond do 10, e 4 e 6 tamb\xe9m. Sab\xea-los de cor \xe9 o ponto."],["Isto vai me deixar melhor em matem\xe1tica no geral?","Torna os fatos b\xe1sicos confiavelmente autom\xe1ticos, o que remove um gargalo em c\xe1lculos maiores. N\xe3o \xe9 um atalho para a intelig\xeancia geral, e as amplas alega\xe7\xf5es de 'turbinar o c\xe9rebro' em torno desses exerc\xedcios n\xe3o t\xeam bom respaldo."],["Isto \xe9 s\xf3 para crian\xe7as?","N\xe3o. O conceito \xe9 ensinado a crian\xe7as, mas o exerc\xedcio \xe9 \xfatil em qualquer idade para afiar a velocidade de c\xe1lculo mental e tirar a ferrugem."]],variants:"Varia\xe7\xf5es comuns mudam o alvo (pares que somam 10, 20, 50, 100), trocam a adi\xe7\xe3o pelo fato de subtra\xe7\xe3o correspondente (dado o todo e uma parte, encontre a outra), usam tr\xeas partes em vez de duas, ou acrescentam decimais e fra\xe7\xf5es para um desafio extra."},hi:{about:"Number Bonds \u090f\u0915 \u092b\u091f\u093e\u092b\u091f \u0905\u0902\u0915\u0917\u0923\u093f\u0924 \u0915\u0938\u0930\u0924 \u0939\u0948 \u091c\u094b \u0938\u0902\u0916\u094d\u092f\u093e\u0913\u0902 \u0915\u0947 \u0909\u0928 \u091c\u094b\u0921\u093c\u094b\u0902 \u0915\u0947 \u0907\u0930\u094d\u0926-\u0917\u093f\u0930\u094d\u0926 \u092c\u0928\u0940 \u0939\u0948 \u091c\u094b \u091c\u0941\u0921\u093c\u0915\u0930 \u0915\u093f\u0938\u0940 \u0932\u0915\u094d\u0937\u094d\u092f \u092a\u0942\u0930\u094d\u0923 \u0938\u0902\u0916\u094d\u092f\u093e \u0924\u0915 \u092a\u0939\u0941\u0901\u091a\u0924\u0947 \u0939\u0948\u0902\u0964 \u0906\u092a\u0915\u094b \u090f\u0915 \u0932\u0915\u094d\u0937\u094d\u092f \u0914\u0930 \u090f\u0915 \u0938\u0902\u0916\u094d\u092f\u093e \u0926\u093f\u0916\u093e\u0908 \u091c\u093e\u0924\u0940 \u0939\u0948, \u0914\u0930 \u0906\u092a\u0915\u093e \u0915\u093e\u092e \u0939\u0948 \u0909\u0938\u0915\u0940 \u091b\u0942\u091f\u0940 \u0939\u0941\u0908 \u091c\u094b\u0921\u093c\u0940\u0926\u093e\u0930 \u0938\u0902\u0916\u094d\u092f\u093e \u0915\u094b \u091c\u093f\u0924\u0928\u0940 \u091c\u0932\u094d\u0926\u0940 \u0939\u094b \u0938\u0915\u0947 \u0926\u094c\u0930-\u0926\u0930-\u0926\u094c\u0930 \u091f\u0948\u092a \u092f\u093e \u091f\u093e\u0907\u092a \u0915\u0930\u0928\u093e, \u0924\u093e\u0915\u093f \u091c\u094b\u0921\u093c\u093f\u092f\u093e\u0901 \u0905\u092a\u0928\u0947-\u0906\u092a \u091c\u093c\u0941\u092c\u093e\u0928 \u092a\u0930 \u0906\u0928\u0947 \u0932\u0917\u0947\u0902\u0964",benefit:"\u092f\u0939 \u0905\u0902\u0915\u0917\u0923\u093f\u0924\u0940\u092f \u0927\u093e\u0930\u093e\u092a\u094d\u0930\u0935\u093e\u0939\u093f\u0924\u093e \u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0930\u093e\u0924\u093e \u0939\u0948, \u092f\u093e\u0928\u0940 \u092c\u0941\u0928\u093f\u092f\u093e\u0926\u0940 \u0938\u0902\u0916\u094d\u092f\u093e-\u0924\u0925\u094d\u092f\u094b\u0902 \u0915\u093e \u0924\u0947\u091c\u093c \u0914\u0930 \u092c\u093f\u0928\u093e \u092e\u0947\u0939\u0928\u0924 \u0915\u093e \u092f\u093e\u0926 \u0906\u0928\u093e\u0964 \u091c\u0948\u0938\u0947-\u091c\u0948\u0938\u0947 \u092f\u093e\u0926 \u0906\u0928\u093e \u0905\u092a\u0928\u0947-\u0906\u092a \u0939\u094b\u0928\u0947 \u0932\u0917\u0924\u093e \u0939\u0948, \u092f\u0939 \u092c\u0921\u093c\u0940 \u0917\u0923\u0928\u093e\u0913\u0902 \u0915\u0947 \u0926\u094c\u0930\u093e\u0928 \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932 \u0938\u094d\u092e\u0943\u0924\u093f \u0915\u094b \u092e\u0941\u0915\u094d\u0924 \u0915\u0930 \u0926\u0947\u0924\u093e \u0939\u0948, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u0906\u092a \u091b\u094b\u091f\u0947 \u091c\u094b\u0921\u093c \u0928\u093f\u0915\u093e\u0932\u0928\u093e \u092c\u0902\u0926 \u0915\u0930\u0915\u0947 \u092c\u0938 \u0909\u0928\u094d\u0939\u0947\u0902 \u092f\u093e\u0926 \u0930\u0916\u0928\u093e \u0936\u0941\u0930\u0942 \u0915\u0930 \u0926\u0947\u0924\u0947 \u0939\u0948\u0902\u0964",history:"\u0928\u0902\u092c\u0930 \u092c\u0949\u0928\u094d\u0921\u094d\u0938 \u0915\u0947 \u092a\u0940\u091b\u0947 \u0915\u093e \u092d\u093e\u0917-\u092d\u093e\u0917-\u092a\u0942\u0930\u094d\u0923 (\u092a\u093e\u0930\u094d\u091f-\u092a\u093e\u0930\u094d\u091f-\u0939\u094b\u0932) \u0935\u093e\u0932\u093e \u0935\u093f\u091a\u093e\u0930 \u092c\u0940\u0938\u0935\u0940\u0902 \u0938\u0926\u0940 \u0915\u0947 \u092e\u0927\u094d\u092f \u092e\u0947\u0902 \u092f\u0942\u0930\u094b\u092a\u0940\u092f \u092a\u094d\u0930\u093e\u0925\u092e\u093f\u0915-\u0917\u0923\u093f\u0924 \u0936\u093f\u0915\u094d\u0937\u0923 \u092e\u0947\u0902 \u092b\u0948\u0932\u093e, \u0938\u093e\u0925 \u0939\u0940 Catherine Stern \u0914\u0930 Georges Cuisenaire \u091c\u0948\u0938\u0940 \u0939\u093e\u0925\u094b\u0902-\u0939\u093e\u0925 \u0935\u093e\u0932\u0940 \u092a\u0926\u094d\u0927\u0924\u093f\u092f\u094b\u0902 \u0915\u0947 \u0938\u093e\u0925\u0964 \u0905\u0902\u0917\u094d\u0930\u0947\u091c\u093c\u0940 \u0936\u092c\u094d\u0926 \"number bonds\" \u0938\u093f\u0902\u0917\u093e\u092a\u0941\u0930 \u0915\u0947 \u0917\u0923\u093f\u0924 \u0915\u0947 \u091c\u093c\u0930\u093f\u090f \u0935\u094d\u092f\u093e\u092a\u0915 \u0930\u0942\u092a \u0938\u0947 \u092a\u0930\u093f\u091a\u093f\u0924 \u0939\u0941\u0906, \u091c\u093f\u0938\u0915\u0947 \u0930\u093e\u0937\u094d\u091f\u094d\u0930\u0940\u092f \u092a\u093e\u0920\u094d\u092f\u0915\u094d\u0930\u092e \u092e\u0947\u0902 1980 \u0915\u0947 \u0926\u0936\u0915 \u092e\u0947\u0902 \u0938\u0941\u0927\u093e\u0930 \u0939\u0941\u0906 \u0914\u0930 \u092c\u093e\u0926 \u092e\u0947\u0902 \u091c\u093f\u0938\u0947 \u0926\u0941\u0928\u093f\u092f\u093e \u092d\u0930 \u092e\u0947\u0902 \u0928\u093f\u0930\u094d\u092f\u093e\u0924 \u0915\u093f\u092f\u093e \u0917\u092f\u093e\u0964",creator:"\u0907\u0938\u0915\u093e \u0915\u094b\u0908 \u090f\u0915\u092e\u093e\u0924\u094d\u0930 \u0906\u0935\u093f\u0937\u094d\u0915\u093e\u0930\u0915 \u0928\u0939\u0940\u0902 \u0939\u0948\u0964 \u0928\u0902\u092c\u0930 \u092c\u0949\u0928\u094d\u0921\u094d\u0938 \u092a\u094d\u0930\u093e\u0925\u092e\u093f\u0915-\u0917\u0923\u093f\u0924 \u092a\u0930\u0902\u092a\u0930\u093e \u0915\u093e \u090f\u0915 \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u0936\u093f\u0915\u094d\u0937\u0923-\u0935\u093f\u091a\u093e\u0930 \u0939\u0948; \u0916\u093e\u0938 \u092d\u093e\u0917-\u092d\u093e\u0917-\u092a\u0942\u0930\u094d\u0923 \u0935\u093e\u0932\u0947 \u0906\u0930\u0947\u0916 \u0914\u0930 \u0907\u0938 \u0928\u093e\u092e \u0915\u094b \u0938\u093f\u0902\u0917\u093e\u092a\u0941\u0930 \u0915\u0947 \u0936\u093f\u0915\u094d\u0937\u093e \u092e\u0902\u0924\u094d\u0930\u093e\u0932\u092f \u0915\u0947 \u092a\u093e\u0920\u094d\u092f\u0915\u094d\u0930\u092e \u0928\u0947 \u0932\u094b\u0915\u092a\u094d\u0930\u093f\u092f \u0915\u093f\u092f\u093e (\u091c\u093f\u0938\u0947 1980 \u0915\u0947 \u0926\u0936\u0915 \u092e\u0947\u0902 Jerome Bruner \u0915\u0947 \u092a\u0939\u0932\u0947 \u0915\u0947 \u092e\u0942\u0930\u094d\u0924-\u091a\u093f\u0924\u094d\u0930\u093e\u0924\u094d\u092e\u0915-\u0905\u092e\u0942\u0930\u094d\u0924 (\u0915\u0902\u0915\u094d\u0930\u0940\u091f-\u092a\u093f\u0915\u094d\u091f\u094b\u0930\u093f\u092f\u0932-\u0910\u092c\u094d\u0938\u094d\u091f\u094d\u0930\u0948\u0915\u094d\u091f) \u0935\u093f\u091a\u093e\u0930\u094b\u0902 \u092a\u0930 \u0916\u0921\u093c\u093e \u0915\u093f\u092f\u093e \u0917\u092f\u093e)\u0964",methods:"\u090f\u0915 \u092c\u093e\u0930 \u092e\u0947\u0902 \u090f\u0915 \u0932\u0915\u094d\u0937\u094d\u092f \u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0940\u091c\u093f\u090f \u091c\u092c \u0924\u0915 \u0909\u0938\u0915\u0947 \u091c\u094b\u0921\u093c\u0947 \u0924\u0941\u0930\u0902\u0924 \u0928 \u0906\u0928\u0947 \u0932\u0917\u0947\u0902, \u092b\u093f\u0930 \u0906\u0917\u0947 \u092c\u0922\u093c\u093f\u090f, \u0914\u0930 \u0918\u0942\u092e-\u092b\u093f\u0930\u0915\u0930 \u0932\u0915\u094d\u0937\u094d\u092f\u094b\u0902 \u0915\u094b \u0906\u092a\u0938 \u092e\u0947\u0902 \u092e\u093f\u0932\u093e \u0926\u0940\u091c\u093f\u090f\u0964 \u0909\u0901\u0917\u0932\u093f\u092f\u094b\u0902 \u092a\u0930 \u0917\u093f\u0928\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u092f\u093e\u0926 \u0938\u0947 \u0928\u093f\u0915\u093e\u0932\u0928\u0947 \u0915\u093e \u0932\u0915\u094d\u0937\u094d\u092f \u0930\u0916\u093f\u090f, \u0914\u0930 \u0925\u094b\u0921\u093c\u0940 \u0905\u0938\u0939\u091c \u0917\u0924\u093f \u0915\u0947 \u0932\u093f\u090f \u091c\u093c\u094b\u0930 \u0932\u0917\u093e\u0907\u090f \u0924\u093e\u0915\u093f \u0906\u092a \u091c\u0935\u093e\u092c \u0928\u093f\u0915\u093e\u0932\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u092f\u093e\u0926 \u0938\u0947 \u0932\u093e \u0930\u0939\u0947 \u0939\u094b\u0902\u0964",duration:"\u091b\u094b\u091f\u093e \u0914\u0930 \u092c\u093e\u0930-\u092c\u093e\u0930, \u0932\u0902\u092c\u0947 \u0914\u0930 \u0915\u092d\u0940-\u0915\u092d\u093e\u0930 \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u0939\u0948: \u0930\u094b\u091c\u093c 5 \u0938\u0947 10 \u092e\u093f\u0928\u091f \u0915\u093e\u092b\u093c\u0940 \u0939\u0948\u0902\u0964 \u0915\u0941\u091b \u0939\u092b\u093c\u094d\u0924\u094b\u0902 \u0924\u0915 \u0930\u094b\u091c\u093c \u0915\u0941\u091b \u092e\u093f\u0928\u091f, \u0905\u092a\u0928\u0947-\u0906\u092a \u0939\u094b\u0928\u0947 \u0935\u093e\u0932\u0940 \u0926\u0915\u094d\u0937\u0924\u093e \u0915\u0947 \u0932\u093f\u090f \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u090f\u0915 \u0932\u0902\u092c\u0947 \u0938\u0924\u094d\u0930 \u0938\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0915\u0930\u0924\u0947 \u0939\u0948\u0902\u0964",research:"\u0938\u092c\u0942\u0924 \u0920\u0940\u0915 \u0909\u0938\u0940 \u092c\u093e\u0924 \u0915\u0947 \u0932\u093f\u090f \u092a\u0941\u0916\u093c\u094d\u0924\u093e \u0939\u0948 \u091c\u093f\u0938\u0947 \u092f\u0939 \u0915\u0938\u0930\u0924 \u0928\u093f\u0936\u093e\u0928\u093e \u092c\u0928\u093e\u0924\u0940 \u0939\u0948 \u2014 \u091c\u093f\u0928 \u0938\u0902\u0916\u094d\u092f\u093e-\u0924\u0925\u094d\u092f\u094b\u0902 \u0915\u093e \u0906\u092a \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902 \u0909\u0928\u094d\u0939\u0947\u0902 \u092f\u093e\u0926 \u0938\u0947 \u0928\u093f\u0915\u093e\u0932\u0928\u0947 \u092e\u0947\u0902 \u0906\u092a \u0924\u0947\u091c\u093c \u0935 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0938\u091f\u0940\u0915 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u0935\u0939 \u0927\u093e\u0930\u093e\u092a\u094d\u0930\u0935\u093e\u0939\u093f\u0924\u093e \u0915\u0920\u093f\u0928 \u0938\u0935\u093e\u0932\u094b\u0902 \u0915\u0947 \u0932\u093f\u090f \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932 \u0938\u094d\u092e\u0943\u0924\u093f \u0915\u094b \u092e\u0941\u0915\u094d\u0924 \u0915\u0930\u0924\u0940 \u0939\u0948 \u0924\u0925\u093e \u0906\u0917\u0947 \u0915\u0940 \u0917\u0923\u093f\u0924-\u0909\u092a\u0932\u092c\u094d\u0927\u093f \u0915\u0940 \u092d\u0935\u093f\u0937\u094d\u092f\u0935\u093e\u0923\u0940 \u0915\u0930\u0924\u0940 \u0939\u0948\u0964 \u092f\u0939 \u0926\u093e\u0935\u093e \u0915\u093f \u0907\u0938 \u0924\u0930\u0939 \u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0906\u092e \u092c\u0941\u0926\u094d\u0927\u093f \u092c\u0922\u093c\u093e\u0924\u093e \u0939\u0948 \u092f\u093e \u0905\u0938\u0902\u092c\u0902\u0927\u093f\u0924 \u0915\u094c\u0936\u0932\u094b\u0902 \u0924\u0915 \u0935\u094d\u092f\u093e\u092a\u0915 \u0939\u0938\u094d\u0924\u093e\u0902\u0924\u0930\u0923 \u092a\u0948\u0926\u093e \u0915\u0930\u0924\u093e \u0939\u0948 \u2014 \u0915\u092e\u091c\u093c\u094b\u0930 \u0914\u0930 \u0915\u093e\u092b\u093c\u0940 \u0939\u0926 \u0924\u0915 \u0905\u0938\u093e\u092c\u093f\u0924 \u0939\u0948; \u0907\u0938\u0938\u0947 \u091c\u0941\u0921\u093c\u093e \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932-\u0938\u094d\u092e\u0943\u0924\u093f \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u092c\u093e\u0930-\u092c\u093e\u0930 \u091f\u093f\u0915\u093e\u090a \u0926\u0942\u0930-\u0939\u0938\u094d\u0924\u093e\u0902\u0924\u0930\u0923 \u0926\u0947\u0928\u0947 \u092e\u0947\u0902 \u0928\u093e\u0915\u093e\u092e \u0930\u0939\u093e \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0915\u093f\u0938\u0940 \u092d\u0940 \u092c\u0921\u093c\u0947 \u0935\u093e\u0926\u0947 \u0915\u094b \u0938\u093e\u0935\u0927\u093e\u0928\u0940 \u0938\u0947 \u0932\u0940\u091c\u093f\u090f\u0964",rec:"10 \u0924\u0915 \u0915\u0947 \u092c\u0949\u0928\u094d\u0921\u094d\u0938 \u0938\u0947 \u0936\u0941\u0930\u0942 \u0915\u0940\u091c\u093f\u090f, \u0909\u0928\u094d\u0939\u0947\u0902 \u0938\u091a\u092e\u0941\u091a \u0924\u0941\u0930\u0902\u0924 \u0935\u093e\u0932\u093e \u092c\u0928\u093e \u0926\u0940\u091c\u093f\u090f, \u0914\u0930 20 \u0935 100 \u0924\u0915 \u0915\u0947 \u092c\u0949\u0928\u094d\u0921\u094d\u0938 \u0915\u0940 \u0913\u0930 \u0924\u092d\u0940 \u092c\u0922\u093c\u093f\u090f \u091c\u092c \u091b\u094b\u091f\u0947 \u0935\u093e\u0932\u0947 \u092c\u093f\u0928\u093e \u092e\u0947\u0939\u0928\u0924 \u0915\u0947 \u0932\u0917\u0928\u0947 \u0932\u0917\u0947\u0902\u0964",faq:[["\u0928\u0902\u092c\u0930 \u092c\u0949\u0928\u094d\u0921 \u0905\u0938\u0932 \u092e\u0947\u0902 \u0915\u094d\u092f\u093e \u0939\u094b\u0924\u093e \u0939\u0948?","\u092f\u0939 \u0938\u0902\u0916\u094d\u092f\u093e\u0913\u0902 \u0915\u093e \u090f\u0915 \u0910\u0938\u093e \u091c\u094b\u0921\u093c\u093e \u0939\u0948 \u091c\u094b \u091c\u0941\u0921\u093c\u0915\u0930 \u0915\u093f\u0938\u0940 \u0916\u093e\u0938 \u092a\u0942\u0930\u094d\u0923 \u0938\u0902\u0916\u094d\u092f\u093e \u0924\u0915 \u092a\u0939\u0941\u0901\u091a\u0924\u093e \u0939\u0948 \u2014 \u092e\u0938\u0932\u0928 3 \u0914\u0930 7 \u092f\u0947 10 \u0915\u0947 \u0932\u093f\u090f \u090f\u0915 \u0928\u0902\u092c\u0930 \u092c\u0949\u0928\u094d\u0921 \u0939\u0948\u0902, \u0914\u0930 4 \u0924\u0925\u093e 6 \u092d\u0940\u0964 \u0907\u0928\u094d\u0939\u0947\u0902 \u091c\u093c\u0941\u092c\u093e\u0928\u0940 \u092f\u093e\u0926 \u0930\u0916\u0928\u093e \u0939\u0940 \u0905\u0938\u0932 \u092e\u0915\u093c\u0938\u0926 \u0939\u0948\u0964"],["\u0915\u094d\u092f\u093e \u092f\u0939 \u092e\u0941\u091d\u0947 \u0915\u0941\u0932 \u092e\u093f\u0932\u093e\u0915\u0930 \u0917\u0923\u093f\u0924 \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u092c\u0928\u093e \u0926\u0947\u0917\u093e?","\u092f\u0939 \u092c\u0941\u0928\u093f\u092f\u093e\u0926\u0940 \u0924\u0925\u094d\u092f\u094b\u0902 \u0915\u094b \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0922\u0902\u0917 \u0938\u0947 \u0905\u092a\u0928\u0947-\u0906\u092a \u0935\u093e\u0932\u093e \u092c\u0928\u093e \u0926\u0947\u0924\u093e \u0939\u0948, \u091c\u093f\u0938\u0938\u0947 \u092c\u0921\u093c\u0940 \u0917\u0923\u0928\u093e\u0913\u0902 \u0915\u0940 \u090f\u0915 \u0930\u0941\u0915\u093e\u0935\u091f \u0939\u091f \u091c\u093e\u0924\u0940 \u0939\u0948\u0964 \u092f\u0939 \u0906\u092e \u092c\u0941\u0926\u094d\u0927\u093f \u0915\u093e \u0915\u094b\u0908 \u0936\u0949\u0930\u094d\u091f\u0915\u091f \u0928\u0939\u0940\u0902 \u0939\u0948, \u0914\u0930 \u0910\u0938\u0940 \u0915\u0938\u0930\u0924\u094b\u0902 \u0915\u0947 \u0907\u0930\u094d\u0926-\u0917\u093f\u0930\u094d\u0926 '\u0926\u093f\u092e\u093e\u0917 \u092c\u0922\u093c\u093e\u0928\u0947' \u0935\u093e\u0932\u0947 \u0935\u094d\u092f\u093e\u092a\u0915 \u0926\u093e\u0935\u094b\u0902 \u0915\u094b \u0905\u091a\u094d\u091b\u093e \u0938\u092e\u0930\u094d\u0925\u0928 \u0939\u093e\u0938\u093f\u0932 \u0928\u0939\u0940\u0902 \u0939\u0948\u0964"],["\u0915\u094d\u092f\u093e \u092f\u0939 \u0938\u093f\u0930\u094d\u092b\u093c \u092c\u091a\u094d\u091a\u094b\u0902 \u0915\u0947 \u0932\u093f\u090f \u0939\u0948?","\u0928\u0939\u0940\u0902\u0964 \u092f\u0939 \u0935\u093f\u091a\u093e\u0930 \u092c\u091a\u094d\u091a\u094b\u0902 \u0915\u094b \u0938\u093f\u0916\u093e\u092f\u093e \u091c\u093e\u0924\u093e \u0939\u0948, \u092e\u0917\u0930 \u092f\u0939 \u0915\u0938\u0930\u0924 \u0915\u093f\u0938\u0940 \u092d\u0940 \u0909\u092e\u094d\u0930 \u092e\u0947\u0902 \u092e\u093e\u0928\u0938\u093f\u0915-\u0905\u0902\u0915\u0917\u0923\u093f\u0924 \u0915\u0940 \u0917\u0924\u093f \u0915\u094b \u0927\u093e\u0930 \u0926\u0947\u0928\u0947 \u0914\u0930 \u091c\u0902\u0917 \u091b\u0941\u0921\u093c\u093e\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0909\u092a\u092f\u094b\u0917\u0940 \u0939\u0948\u0964"]],variants:"\u0906\u092e \u092c\u0926\u0932\u093e\u0935 \u0932\u0915\u094d\u0937\u094d\u092f \u0915\u094b \u092c\u0926\u0932\u0924\u0947 \u0939\u0948\u0902 (10, 20, 50, 100 \u0924\u0915 \u0915\u0947 \u092c\u0949\u0928\u094d\u0921\u094d\u0938), \u091c\u094b\u0921\u093c \u0915\u0940 \u091c\u0917\u0939 \u0909\u0938\u0938\u0947 \u092e\u0947\u0932 \u0916\u093e\u0924\u093e \u0918\u091f\u093e\u0935-\u0924\u0925\u094d\u092f \u0930\u0916 \u0926\u0947\u0924\u0947 \u0939\u0948\u0902 (\u092a\u0942\u0930\u094d\u0923 \u0914\u0930 \u090f\u0915 \u092d\u093e\u0917 \u0926\u093f\u092f\u093e \u0939\u094b, \u0924\u094b \u0926\u0942\u0938\u0930\u093e \u0928\u093f\u0915\u093e\u0932\u093f\u090f), \u0926\u094b \u0915\u0947 \u092c\u091c\u093e\u092f \u0924\u0940\u0928 \u092d\u093e\u0917 \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902, \u092f\u093e \u0905\u0924\u093f\u0930\u093f\u0915\u094d\u0924 \u091a\u0941\u0928\u094c\u0924\u0940 \u0915\u0947 \u0932\u093f\u090f \u0926\u0936\u092e\u0932\u0935 \u0914\u0930 \u092d\u093f\u0928\u094d\u0928 \u091c\u094b\u0921\u093c \u0926\u0947\u0924\u0947 \u0939\u0948\u0902\u0964"},zh:{about:"\u300a\u6570\u5b57\u642d\u6863\u300b\u662f\u4e00\u4e2a\u5feb\u901f\u7b97\u672f\u7ec3\u4e60\uff0c\u56f4\u7ed5\u300e\u76f8\u52a0\u51d1\u6210\u67d0\u4e2a\u76ee\u6807\u6574\u6570\u7684\u6570\u5b57\u5bf9\u300f\u5c55\u5f00\u3002\u5c4f\u5e55\u4f1a\u7ed9\u4f60\u4e00\u4e2a\u76ee\u6807\u548c\u4e00\u4e2a\u6570\u5b57\uff0c\u4f60\u7684\u4efb\u52a1\u662f\u5c3d\u5feb\u70b9\u51fa\u6216\u8f93\u5165\u5b83\u7f3a\u5931\u7684\u90a3\u4e2a\u642d\u6863\uff0c\u4e00\u8f6e\u63a5\u4e00\u8f6e\uff0c\u76f4\u5230\u8fd9\u4e9b\u914d\u5bf9\u53d8\u5f97\u81ea\u52a8\u5316\u3002",benefit:"\u5b83\u8bad\u7ec3\u7b97\u672f\u6d41\u7545\u5ea6\uff0c\u4e5f\u5c31\u662f\u5bf9\u57fa\u672c\u6570\u5b57\u4e8b\u5b9e\u5feb\u901f\u800c\u6beb\u4e0d\u8d39\u529b\u7684\u56de\u5fc6\u3002\u5f53\u56de\u5fc6\u53d8\u5f97\u81ea\u52a8\u5316\uff0c\u5b83\u5c31\u80fd\u5728\u66f4\u5927\u7684\u8ba1\u7b97\u4e2d\u817e\u51fa\u5de5\u4f5c\u8bb0\u5fc6\uff0c\u56e0\u4e3a\u4f60\u4e0d\u518d\u53bb\u8ba1\u7b97\u5c0f\u7684\u548c\uff0c\u800c\u662f\u76f4\u63a5\u628a\u5b83\u4eec\u8bb0\u8d77\u6765\u3002",history:"\u6570\u5b57\u642d\u6863\u80cc\u540e\u300e\u90e8\u5206\u2014\u90e8\u5206\u2014\u6574\u4f53\u300f\u7684\u601d\u60f3\uff0c\u572820\u4e16\u7eaa\u4e2d\u53f6\u968f\u7740Catherine Stern\u548cGeorges Cuisenaire\u7b49\u4eba\u7684\u52a8\u624b\u6559\u5b66\u6cd5\uff0c\u5728\u6b27\u6d32\u7684\u5c0f\u5b66\u6570\u5b66\u6559\u5b66\u4e2d\u4f20\u64ad\u5f00\u6765\u3002\u800c\u82f1\u6587\u672f\u8bed\u300enumber bonds\u300f\u5219\u662f\u901a\u8fc7\u65b0\u52a0\u5761\u6570\u5b66\u5e7f\u4e3a\u4eba\u77e5\u7684\u2014\u2014\u65b0\u52a0\u5761\u572820\u4e16\u7eaa80\u5e74\u4ee3\u6539\u9769\u4e86\u672c\u56fd\u8bfe\u7a0b\uff0c\u540e\u6765\u53c8\u8f93\u51fa\u5230\u5168\u4e16\u754c\u3002",creator:"\u5b83\u6ca1\u6709\u5355\u4e00\u7684\u53d1\u660e\u8005\u3002\u6570\u5b57\u642d\u6863\u662f\u6765\u81ea\u5c0f\u5b66\u6570\u5b66\u4f20\u7edf\u7684\u4e00\u4e2a\u901a\u7528\u6559\u5b66\u6982\u5ff5\uff1b\u90a3\u4e2a\u5177\u4f53\u7684\u300e\u90e8\u5206\u2014\u90e8\u5206\u2014\u6574\u4f53\u300f\u793a\u610f\u56fe\u548c\u8fd9\u4e2a\u540d\u79f0\uff0c\u662f\u7531\u65b0\u52a0\u5761\u6559\u80b2\u90e8\u7684\u8bfe\u7a0b\u52a0\u4ee5\u63a8\u5e7f\u7684\uff08\u5b83\u572820\u4e16\u7eaa80\u5e74\u4ee3\u9010\u6b65\u5efa\u7acb\uff0c\u57fa\u7840\u662fJerome Bruner\u66f4\u65e9\u63d0\u51fa\u7684\u300e\u5177\u4f53\u2014\u56fe\u50cf\u2014\u62bd\u8c61\u300f\u601d\u60f3\uff09\u3002",methods:"\u4e00\u6b21\u53ea\u8bad\u7ec3\u4e00\u4e2a\u76ee\u6807\uff0c\u76f4\u5230\u5c5e\u4e8e\u5b83\u7684\u90a3\u4e9b\u6570\u5b57\u5bf9\u8131\u53e3\u800c\u51fa\uff0c\u518d\u6362\u4e0b\u4e00\u4e2a\uff0c\u4e4b\u540e\u518d\u7ed5\u56de\u6765\u628a\u591a\u4e2a\u76ee\u6807\u6df7\u5728\u4e00\u8d77\u7ec3\u3002\u8ffd\u6c42\u7684\u662f\u56de\u5fc6\uff0c\u800c\u4e0d\u662f\u63b0\u624b\u6307\u6570\u6570\uff0c\u5e76\u628a\u8282\u594f\u63a8\u5230\u7565\u5fae\u4e0d\u9002\u7684\u7a0b\u5ea6\uff0c\u8ba9\u4f60\u662f\u5728\u8c03\u53d6\u7b54\u6848\uff0c\u800c\u4e0d\u662f\u5728\u73b0\u573a\u7b97\u51fa\u5b83\u4eec\u3002",duration:"\u77ed\u800c\u9891\u7e41\u80dc\u8fc7\u957f\u800c\u7a00\u5c11\uff1a\u6bcf\u59295\u523010\u5206\u949f\u5c31\u8db3\u591f\u3002\u6bcf\u5929\u7ec3\u51e0\u5206\u949f\u3001\u575a\u6301\u4e24\u5468\uff0c\u5bf9\u81ea\u52a8\u5316\u7684\u5e2e\u52a9\u8fdc\u80dc\u8fc7\u6bcf\u5468\u4e00\u6b21\u7684\u6f2b\u957f\u7ec3\u4e60\u3002",research:"\u8bc1\u636e\u624e\u5b9e\u5730\u652f\u6301\u4e86\u8fd9\u9879\u7ec3\u4e60\u6240\u9488\u5bf9\u7684\u76ee\u6807\u2014\u2014\u4f60\u4f1a\u8d8a\u6765\u8d8a\u5feb\u3001\u8d8a\u6765\u8d8a\u51c6\u5730\u56de\u5fc6\u8d77\u4f60\u6240\u7ec3\u4e60\u7684\u6570\u5b57\u4e8b\u5b9e\uff0c\u800c\u8fd9\u79cd\u6d41\u7545\u5ea6\u80fd\u4e3a\u66f4\u96be\u7684\u9898\u76ee\u817e\u51fa\u5de5\u4f5c\u8bb0\u5fc6\uff0c\u5e76\u80fd\u9884\u6d4b\u65e5\u540e\u7684\u6570\u5b66\u6210\u5c31\u3002\u81f3\u4e8e\u8fd9\u7c7b\u7ec3\u4e60\u80fd\u63d0\u5347\u4e00\u822c\u667a\u529b\u6216\u4ea7\u751f\u5e7f\u6cdb\u8fc1\u79fb\u5230\u4e0d\u76f8\u5173\u6280\u80fd\u7684\u8bf4\u6cd5\u5219\u5f88\u8584\u5f31\u3001\u57fa\u672c\u672a\u83b7\u8bc1\u5b9e\uff1b\u76f8\u5173\u7684\u5de5\u4f5c\u8bb0\u5fc6\u8bad\u7ec3\u4e00\u518d\u672a\u80fd\u5e26\u6765\u6301\u4e45\u7684\u8fdc\u8fc1\u79fb\uff0c\u6240\u4ee5\u5bf9\u4efb\u4f55\u5b8f\u5927\u7684\u627f\u8bfa\u90fd\u8981\u4fdd\u6301\u8c28\u614e\u3002",rec:"\u4ece\u51d110\u7684\u642d\u6863\u5f00\u59cb\uff0c\u628a\u5b83\u4eec\u7ec3\u5230\u771f\u6b63\u8131\u53e3\u800c\u51fa\uff0c\u7136\u540e\u53ea\u6709\u5728\u8f83\u5c0f\u7684\u90a3\u4e9b\u5df2\u7ecf\u6beb\u4e0d\u8d39\u529b\u4e4b\u540e\uff0c\u624d\u8fdb\u9636\u5230\u51d120\u548c\u51d1100\u7684\u642d\u6863\u3002",faq:[["\u6570\u5b57\u642d\u6863\u5230\u5e95\u662f\u4ec0\u4e48\uff1f","\u5b83\u662f\u4e00\u5bf9\u76f8\u52a0\u51d1\u6210\u67d0\u4e2a\u7279\u5b9a\u6574\u6570\u7684\u6570\u5b57\u2014\u2014\u4f8b\u59823\u548c7\u662f\u51d110\u7684\u4e00\u4e2a\u6570\u5b57\u642d\u6863\uff0c4\u548c6\u4e5f\u662f\u3002\u628a\u5b83\u4eec\u70c2\u719f\u4e8e\u5fc3\u6b63\u662f\u5173\u952e\u6240\u5728\u3002"],["\u8fd9\u4f1a\u8ba9\u6211\u6574\u4f53\u4e0a\u66f4\u64c5\u957f\u6570\u5b66\u5417\uff1f","\u5b83\u4e00\u5b9a\u4f1a\u8ba9\u57fa\u672c\u7684\u6570\u5b57\u4e8b\u5b9e\u53d8\u5f97\u81ea\u52a8\u5316\uff0c\u4ece\u800c\u6d88\u9664\u5927\u578b\u8ba1\u7b97\u4e2d\u7684\u4e00\u4e2a\u74f6\u9888\u3002\u5b83\u5e76\u4e0d\u662f\u901a\u5f80\u4e00\u822c\u667a\u529b\u7684\u6377\u5f84\uff0c\u800c\u56f4\u7ed5\u6b64\u7c7b\u7ec3\u4e60\u7684\u90a3\u4e9b\u5bbd\u6cdb\u7684\u300e\u5065\u8111\u300f\u8bf4\u6cd5\u4e5f\u6ca1\u6709\u5f97\u5230\u5145\u5206\u652f\u6301\u3002"],["\u8fd9\u53ea\u9002\u5408\u5c0f\u5b69\u5b50\u5417\uff1f","\u4e0d\u662f\u3002\u8fd9\u4e2a\u6982\u5ff5\u662f\u6559\u7ed9\u5b69\u5b50\u7684\uff0c\u4f46\u8fd9\u9879\u7ec3\u4e60\u5728\u4efb\u4f55\u5e74\u9f84\u90fd\u6709\u7528\uff0c\u53ef\u4ee5\u78e8\u5feb\u5fc3\u7b97\u901f\u5ea6\u3001\u628a\u751f\u758f\u6296\u843d\u6389\u3002"]],variants:"\u5e38\u89c1\u7684\u53d8\u4f53\u4f1a\u6539\u53d8\u76ee\u6807\uff08\u51d110\u300120\u300150\u3001100\u7684\u642d\u6863\uff09\uff0c\u628a\u52a0\u6cd5\u6362\u6210\u5bf9\u5e94\u7684\u51cf\u6cd5\u4e8b\u5b9e\uff08\u7ed9\u51fa\u6574\u4f53\u548c\u4e00\u4e2a\u90e8\u5206\uff0c\u6c42\u53e6\u4e00\u4e2a\u90e8\u5206\uff09\uff0c\u7528\u4e09\u4e2a\u90e8\u5206\u800c\u975e\u4e24\u4e2a\uff0c\u6216\u8005\u52a0\u5165\u5c0f\u6570\u548c\u5206\u6570\u4f5c\u4e3a\u989d\u5916\u6311\u6218\u3002"}},ospan:{ru:{about:"\u0412 OSpan \u0432\u044b \u0434\u0435\u043b\u0430\u0435\u0442\u0435 \u0434\u0432\u0430 \u0434\u0435\u043b\u0430 \u0432\u043f\u0435\u0440\u0435\u043c\u0435\u0436\u043a\u0443: \u0447\u0438\u0442\u0430\u0435\u0442\u0435 \u043f\u0440\u043e\u0441\u0442\u043e\u0435 \u0430\u0440\u0438\u0444\u043c\u0435\u0442\u0438\u0447\u0435\u0441\u043a\u043e\u0435 \u0440\u0430\u0432\u0435\u043d\u0441\u0442\u0432\u043e \u0438 \u0440\u0435\u0448\u0430\u0435\u0442\u0435, \u0432\u0435\u0440\u043d\u043e\u0435 \u043e\u043d\u043e \u0438\u043b\u0438 \u043d\u0435\u0442, \u0430 \u0441\u0440\u0430\u0437\u0443 \u043f\u043e\u0441\u043b\u0435 \u043d\u0430 \u043c\u0438\u0433 \u043f\u043e\u043a\u0430\u0437\u044b\u0432\u0430\u044e\u0442 \u043e\u0434\u043d\u0443 \u0431\u0443\u043a\u0432\u0443, \u043a\u043e\u0442\u043e\u0440\u0443\u044e \u043d\u0443\u0436\u043d\u043e \u0437\u0430\u043f\u043e\u043c\u043d\u0438\u0442\u044c. \u041f\u043e\u0441\u043b\u0435 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u0438\u0445 \u0442\u0430\u043a\u0438\u0445 \u0441\u0432\u044f\u0437\u043e\u043a \u0441\u0447\u0451\u0442-\u0431\u0443\u043a\u0432\u0430 \u0432\u044b \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0438\u0442\u0435 \u0431\u0443\u043a\u0432\u044b \u0432 \u0442\u043e\u043c \u0436\u0435 \u043f\u043e\u0440\u044f\u0434\u043a\u0435, \u0432 \u043a\u0430\u043a\u043e\u043c \u043e\u043d\u0438 \u043f\u043e\u044f\u0432\u043b\u044f\u043b\u0438\u0441\u044c. \u0421\u0443\u0442\u044c \u0432 \u0442\u043e\u043c, \u0447\u0442\u043e\u0431\u044b \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0442\u044c \u0441\u043f\u0438\u0441\u043e\u043a, \u043f\u043e\u043a\u0430 \u043e\u0442\u0432\u043b\u0435\u043a\u0430\u044e\u0449\u0438\u0439 \u0441\u0447\u0451\u0442 \u043f\u043e\u0441\u0442\u043e\u044f\u043d\u043d\u043e \u043d\u043e\u0440\u043e\u0432\u0438\u0442 \u0435\u0433\u043e \u0432\u044b\u0442\u0435\u0441\u043d\u0438\u0442\u044c.",benefit:"\u0422\u0440\u0435\u043d\u0430\u0436\u0451\u0440 \u043d\u0430\u0433\u0440\u0443\u0436\u0430\u0435\u0442 \u043e\u0431\u044a\u0451\u043c \u0440\u0430\u0431\u043e\u0447\u0435\u0439 \u043f\u0430\u043c\u044f\u0442\u0438, \u0442\u043e \u0435\u0441\u0442\u044c \u0441\u043f\u043e\u0441\u043e\u0431\u043d\u043e\u0441\u0442\u044c \u0434\u0435\u0440\u0436\u0430\u0442\u044c \u0432 \u0433\u043e\u043b\u043e\u0432\u0435 \u043d\u0430\u0431\u043e\u0440 \u044d\u043b\u0435\u043c\u0435\u043d\u0442\u043e\u0432, \u043f\u043e\u043a\u0430 \u0432\u0442\u043e\u0440\u043e\u0439 \u043f\u0440\u043e\u0446\u0435\u0441\u0441 \u043e\u0442\u0432\u043b\u0435\u043a\u0430\u0435\u0442 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u043d\u0430 \u0441\u0435\u0431\u044f. \u0418\u043c\u0435\u043d\u043d\u043e \u044d\u0442\u043e \u043e\u0434\u043d\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u043e\u0435 \u0436\u043e\u043d\u0433\u043b\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u0435 \u0445\u0440\u0430\u043d\u0435\u043d\u0438\u0435\u043c \u0438 \u043e\u0431\u0440\u0430\u0431\u043e\u0442\u043a\u043e\u0439 \u0438 \u043d\u0430\u0433\u0440\u0443\u0436\u0430\u0435\u0442\u0441\u044f, \u043f\u043b\u044e\u0441 \u0443\u0441\u0442\u043e\u0439\u0447\u0438\u0432\u043e\u0441\u0442\u044c \u043a \u043f\u043e\u043c\u0435\u0445\u0430\u043c.",history:"\u0417\u0430\u0434\u0430\u0447\u0430 \u043f\u043e\u044f\u0432\u0438\u043b\u0430\u0441\u044c \u0432 1989 \u0433\u043e\u0434\u0443 \u043a\u0430\u043a \u043b\u0430\u0431\u043e\u0440\u0430\u0442\u043e\u0440\u043d\u0430\u044f \u043c\u0435\u0440\u043a\u0430 \u0440\u0430\u0431\u043e\u0447\u0435\u0439 \u043f\u0430\u043c\u044f\u0442\u0438, \u0430 \u043d\u0435 \u043a\u0430\u043a \u0438\u0433\u0440\u0430, \u0438 \u0441\u0442\u0430\u043b\u0430 \u043e\u0434\u043d\u043e\u0439 \u0438\u0437 \u0441\u0430\u043c\u044b\u0445 \u0446\u0438\u0442\u0438\u0440\u0443\u0435\u043c\u044b\u0445 \u043c\u0435\u0442\u043e\u0434\u0438\u043a \u043a\u043e\u043c\u043f\u043b\u0435\u043a\u0441\u043d\u043e\u0433\u043e \u043e\u0431\u044a\u0451\u043c\u0430 \u0432 \u043a\u043e\u0433\u043d\u0438\u0442\u0438\u0432\u043d\u043e\u0439 \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u0438. \u0412 2005 \u0433\u043e\u0434\u0443 \u0410\u043d\u0441\u0432\u043e\u0440\u0442, \u0425\u0430\u0439\u0442\u0446, \u0428\u0440\u043e\u043a \u0438 \u042d\u043d\u0433\u043b \u0432\u044b\u043f\u0443\u0441\u0442\u0438\u043b\u0438 \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u0443\u044e \u0432\u0435\u0440\u0441\u0438\u044e \u0441 \u0443\u043f\u0440\u0430\u0432\u043b\u0435\u043d\u0438\u0435\u043c \u043c\u044b\u0448\u044c\u044e, \u043a\u043e\u0442\u043e\u0440\u0430\u044f \u0441\u0430\u043c\u0430 \u0441\u0447\u0438\u0442\u0430\u043b\u0430 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442, \u0438 \u044d\u0442\u043e \u0432\u044b\u043d\u0435\u0441\u043b\u043e \u0435\u0451 \u0434\u0430\u043b\u0435\u043a\u043e \u0437\u0430 \u043f\u0440\u0435\u0434\u0435\u043b\u044b \u0438\u0441\u0445\u043e\u0434\u043d\u043e\u0439 \u043b\u0430\u0431\u043e\u0440\u0430\u0442\u043e\u0440\u0438\u0438 \u0432 \u0441\u043e\u0442\u043d\u0438 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u0439, \u0430 \u043f\u043e\u0437\u0436\u0435 \u0438 \u0432 \u043f\u0440\u0438\u043b\u043e\u0436\u0435\u043d\u0438\u044f \u0434\u043b\u044f \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0438 \u043c\u043e\u0437\u0433\u0430.",creator:"\u041c\u0435\u0442\u043e\u0434\u0438\u043a\u0443 \u0441\u043e\u0437\u0434\u0430\u043b\u0438 \u041c\u044d\u0440\u0438\u043b\u0438\u043d \u0422\u0451\u0440\u043d\u0435\u0440 \u0438 \u0420\u044d\u043d\u0434\u0430\u043b\u043b (\u0420\u044d\u043d\u0434\u0438) \u042d\u043d\u0433\u043b \u0432 1989 \u0433\u043e\u0434\u0443 \u0432 \u0423\u043d\u0438\u0432\u0435\u0440\u0441\u0438\u0442\u0435\u0442\u0435 \u042e\u0436\u043d\u043e\u0439 \u041a\u0430\u0440\u043e\u043b\u0438\u043d\u044b \u043a\u0430\u043a \u043c\u0435\u0440\u0443 \u043e\u0431\u044a\u0451\u043c\u0430 \u0440\u0430\u0431\u043e\u0447\u0435\u0439 \u043f\u0430\u043c\u044f\u0442\u0438. \u0428\u0438\u0440\u043e\u043a\u043e \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0435\u043c\u0443\u044e \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u0443\u044e \u0432\u0435\u0440\u0441\u0438\u044e \u043f\u043e\u0441\u0442\u0440\u043e\u0438\u043b\u0438 \u041d\u044d\u0448 \u0410\u043d\u0441\u0432\u043e\u0440\u0442, \u0420\u0438\u0447\u0430\u0440\u0434 \u0425\u0430\u0439\u0442\u0446, \u0419\u043e\u0437\u0435\u0444 \u0428\u0440\u043e\u043a \u0438 \u0420\u044d\u043d\u0434\u0430\u043b\u043b \u042d\u043d\u0433\u043b \u0432 2005 \u0433\u043e\u0434\u0443.",methods:"\u0421\u043d\u0430\u0447\u0430\u043b\u0430 \u0437\u0430\u043a\u0440\u0435\u043f\u043b\u044f\u0439\u0442\u0435 \u043f\u043e\u0440\u044f\u0434\u043e\u043a: \u043f\u0440\u043e \u0441\u0435\u0431\u044f \u043f\u0440\u043e\u0433\u043e\u0432\u0430\u0440\u0438\u0432\u0430\u0439\u0442\u0435 \u0440\u0430\u0441\u0442\u0443\u0449\u0443\u044e \u0446\u0435\u043f\u043e\u0447\u043a\u0443 \u0431\u0443\u043a\u0432 \u0432 \u0440\u043e\u0432\u043d\u043e\u043c \u0440\u0438\u0442\u043c\u0435, \u043f\u043e\u0442\u043e\u043c \u043f\u043e\u043b\u043d\u043e\u0441\u0442\u044c\u044e \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0430\u0439\u0442\u0435\u0441\u044c \u043d\u0430 \u0440\u0430\u0432\u0435\u043d\u0441\u0442\u0432\u043e \u0438 \u043e\u0431\u0440\u0430\u0442\u043d\u043e. \u041d\u0435 \u043f\u043e\u0437\u0432\u043e\u043b\u044f\u0439\u0442\u0435 \u0441\u0447\u0451\u0442\u0443 \u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u044c\u0441\u044f \u043f\u043e\u0432\u043e\u0434\u043e\u043c \u043f\u043e\u0442\u0435\u0440\u044f\u0442\u044c \u0431\u0443\u043a\u0432\u0443 \u0438 \u043d\u0435 \u0440\u0430\u0441\u0442\u044f\u0433\u0438\u0432\u0430\u0439\u0442\u0435 \u0441\u0447\u0451\u0442 \u0442\u0430\u043a, \u0447\u0442\u043e\u0431\u044b \u043d\u0430 \u0434\u0435\u043b\u0435 \u043f\u0440\u043e\u0441\u0442\u043e \u0434\u043e\u0443\u0447\u0438\u0432\u0430\u0442\u044c \u0431\u0443\u043a\u0432\u044b \u0432 \u043f\u0430\u0443\u0437\u0430\u0445. \u041f\u043e\u0434\u043d\u0438\u043c\u0430\u0439\u0442\u0435 \u0434\u043b\u0438\u043d\u0443 \u043d\u0430\u0431\u043e\u0440\u0430 \u0442\u043e\u043b\u044c\u043a\u043e \u043a\u043e\u0433\u0434\u0430 \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u0435\u0434\u0435\u043d\u0438\u0435 \u0441\u0442\u0430\u0431\u0438\u043b\u044c\u043d\u043e, \u0430 \u043d\u0435 \u043a\u043e\u0433\u0434\u0430 \u043e\u043d\u043e \u043b\u0438\u0448\u044c \u043a\u0430\u0436\u0435\u0442\u0441\u044f \u043b\u0451\u0433\u043a\u0438\u043c.",duration:"\u041b\u0443\u0447\u0448\u0435 \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u0435 \u0441\u043e\u0431\u0440\u0430\u043d\u043d\u044b\u0435 \u043f\u043e\u0434\u0445\u043e\u0434\u044b: \u043f\u0440\u0438\u043c\u0435\u0440\u043d\u043e 10\u201315 \u043c\u0438\u043d\u0443\u0442, \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0440\u0430\u0437 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e. \u041e\u0441\u0442\u0430\u043d\u0430\u0432\u043b\u0438\u0432\u0430\u0439\u0442\u0435\u0441\u044c, \u043a\u0430\u043a \u0442\u043e\u043b\u044c\u043a\u043e \u043f\u0430\u0434\u0430\u0435\u0442 \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u044c, \u043f\u043e\u0442\u043e\u043c\u0443 \u0447\u0442\u043e \u0443\u0441\u0442\u0430\u043b\u044b\u0435 \u043d\u0435\u0431\u0440\u0435\u0436\u043d\u044b\u0435 \u043f\u043e\u0432\u0442\u043e\u0440\u044b \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u044e\u0442 \u043d\u0435 \u043e\u0431\u044a\u0451\u043c, \u0430 \u043f\u043b\u043e\u0445\u0438\u0435 \u043f\u0440\u0438\u0432\u044b\u0447\u043a\u0438.",research:"\u0414\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u043d\u0435\u0435 \u0432\u0441\u0435\u0433\u043e \u0440\u043e\u0432\u043d\u043e \u0442\u043e, \u0447\u0435\u0433\u043e \u0438 \u0436\u0434\u0451\u0448\u044c: \u0432\u044b \u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u0435\u0441\u044c \u043b\u0443\u0447\u0448\u0435 \u0432 \u0441\u0430\u043c\u043e\u043c OSpan \u0438 \u0432 \u0431\u043b\u0438\u0437\u043a\u0438\u0445 \u0437\u0430\u0434\u0430\u0447\u0430\u0445 \u043a\u043e\u043c\u043f\u043b\u0435\u043a\u0441\u043d\u043e\u0433\u043e \u043e\u0431\u044a\u0451\u043c\u0430. \u041a\u0430\u043a \u0438\u0437\u043c\u0435\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0439 \u0438\u043d\u0441\u0442\u0440\u0443\u043c\u0435\u043d\u0442 \u043e\u043d \u043d\u0430\u0434\u0451\u0436\u043d\u043e \u043f\u0440\u0435\u0434\u0441\u043a\u0430\u0437\u044b\u0432\u0430\u0435\u0442 \u043f\u043e\u0434\u0432\u0438\u0436\u043d\u044b\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442, \u043d\u043e \u044d\u0442\u043e \u043a\u043e\u0440\u0440\u0435\u043b\u044f\u0446\u0438\u044f, \u0430 \u043d\u0435 \u0434\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432\u043e, \u0447\u0442\u043e \u043d\u0430\u0442\u0430\u0441\u043a\u0438\u0432\u0430\u043d\u0438\u0435 \u043d\u0430 \u043d\u0451\u043c \u043f\u043e\u0434\u043d\u0438\u043c\u0430\u0435\u0442 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442. \u041a\u043e\u0433\u0434\u0430 \u043b\u044e\u0434\u0435\u0439 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043b\u044c\u043d\u043e \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u0430\u043b\u0438 \u043d\u0430 \u043a\u043e\u043c\u043f\u043b\u0435\u043a\u0441\u043d\u043e\u043c \u043e\u0431\u044a\u0451\u043c\u0435, \u0425\u0430\u0440\u0440\u0438\u0441\u043e\u043d \u0441 \u043a\u043e\u043b\u043b\u0435\u0433\u0430\u043c\u0438 (2013) \u043e\u0431\u043d\u0430\u0440\u0443\u0436\u0438\u043b\u0438 \u043f\u0435\u0440\u0435\u043d\u043e\u0441 \u043d\u0430 \u0434\u0440\u0443\u0433\u0438\u0435 span-\u0437\u0430\u0434\u0430\u0447\u0438, \u043d\u043e \u043d\u0435 \u043d\u0430 \u043f\u043e\u0434\u0432\u0438\u0436\u043d\u044b\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442, \u0430 \u0420\u0435\u0434\u0438\u043a \u0441 \u043a\u043e\u043b\u043b\u0435\u0433\u0430\u043c\u0438 (2013) \u043d\u0435 \u043d\u0430\u0448\u043b\u0438 \u0448\u0438\u0440\u043e\u043a\u043e\u0433\u043e \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0430 \u0432\u043e\u0432\u0441\u0435, \u0442\u0430\u043a \u0447\u0442\u043e \u043a \u0437\u0430\u044f\u0432\u043b\u0435\u043d\u0438\u044f\u043c \u043e \u0440\u043e\u0441\u0442\u0435 IQ \u0438\u043b\u0438 \u043e\u0431\u0449\u0435\u0439 \u0441\u0438\u043b\u044b \u0443\u043c\u0430 \u0441\u0442\u043e\u0438\u0442 \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u044c\u0441\u044f \u043e\u0441\u0442\u043e\u0440\u043e\u0436\u043d\u043e.",rec:"\u041e\u0442\u043d\u043e\u0441\u0438\u0442\u0435\u0441\u044c \u043a \u0440\u0430\u0432\u0435\u043d\u0441\u0442\u0432\u0430\u043c \u043a\u0430\u043a \u043a \u043d\u0430\u0441\u0442\u043e\u044f\u0449\u0435\u043c\u0443 \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u0451\u0440\u0443: \u043e\u0442\u0432\u0435\u0447\u0430\u0439\u0442\u0435 \u043d\u0430 \u043a\u0430\u0436\u0434\u043e\u0435 \u0447\u0435\u0441\u0442\u043d\u043e \u0438 \u0431\u044b\u0441\u0442\u0440\u043e, \u0430 \u043d\u0435 \u043f\u0440\u043e\u0431\u0435\u0433\u0430\u0439\u0442\u0435 \u043c\u0438\u043c\u043e \u043d\u0438\u0445, \u0447\u0442\u043e\u0431\u044b \u043f\u043e\u0431\u0435\u0440\u0435\u0447\u044c \u0431\u0443\u043a\u0432\u044b.",faq:[["\u0410\u0440\u0438\u0444\u043c\u0435\u0442\u0438\u043a\u0430 \u0434\u043e\u043b\u0436\u043d\u0430 \u0431\u044b\u0442\u044c \u0441\u043b\u043e\u0436\u043d\u043e\u0439?","\u041d\u0435\u0442. \u0420\u0430\u0432\u0435\u043d\u0441\u0442\u0432\u0430 \u043d\u0430\u043c\u0435\u0440\u0435\u043d\u043d\u043e \u043b\u0451\u0433\u043a\u0438\u0435. \u041e\u043d\u0438 \u043d\u0443\u0436\u043d\u044b, \u0447\u0442\u043e\u0431\u044b \u0437\u0430\u043d\u044f\u0442\u044c \u0438 \u043e\u0442\u0432\u043b\u0435\u0447\u044c \u0432\u0430\u0441, \u0430 \u043d\u0435 \u043f\u0440\u043e\u0432\u0435\u0440\u0438\u0442\u044c \u0441\u0447\u0451\u0442, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u0432\u0441\u044f \u0442\u0440\u0443\u0434\u043d\u043e\u0441\u0442\u044c \u0432 \u0442\u043e\u043c, \u0447\u0442\u043e\u0431\u044b \u0443\u0434\u0435\u0440\u0436\u0430\u0442\u044c \u0431\u0443\u043a\u0432\u044b, \u043f\u043e\u043a\u0430 \u0432\u044b \u0438\u0445 \u043e\u0431\u0440\u0430\u0431\u0430\u0442\u044b\u0432\u0430\u0435\u0442\u0435."],["\u042f \u0441\u0442\u0430\u043d\u0443 \u0443\u043c\u043d\u0435\u0435 \u0432 \u0446\u0435\u043b\u043e\u043c?","\u0427\u0435\u0441\u0442\u043d\u043e, \u0441\u043a\u043e\u0440\u0435\u0435 \u0432\u0441\u0435\u0433\u043e \u043d\u0435\u0442 \u0432 \u0448\u0438\u0440\u043e\u043a\u043e\u043c \u0441\u043c\u044b\u0441\u043b\u0435. \u0412\u044b \u0437\u0430\u043c\u0435\u0442\u043d\u043e \u043f\u0440\u0438\u0431\u0430\u0432\u0438\u0442\u0435 \u0432 \u0441\u0430\u043c\u043e\u0439 \u044d\u0442\u043e\u0439 \u0437\u0430\u0434\u0430\u0447\u0435 \u0438 \u043f\u043e\u0445\u043e\u0436\u0438\u0445 \u0442\u0435\u0441\u0442\u0430\u0445 \u043d\u0430 \u043e\u0431\u044a\u0451\u043c \u043f\u0430\u043c\u044f\u0442\u0438, \u043d\u043e \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u0438\u0440\u0443\u0435\u043c\u044b\u0435 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u044f \u0432 \u0446\u0435\u043b\u043e\u043c \u043d\u0435 \u043f\u043e\u043a\u0430\u0437\u0430\u043b\u0438 \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0430 \u043d\u0430 \u043f\u043e\u0434\u0432\u0438\u0436\u043d\u044b\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0438\u043b\u0438 \u043f\u043e\u0432\u0441\u0435\u0434\u043d\u0435\u0432\u043d\u043e\u0435 \u043c\u044b\u0448\u043b\u0435\u043d\u0438\u0435."],["\u0417\u0430\u0447\u0435\u043c \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0438\u0442\u044c \u0431\u0443\u043a\u0432\u044b \u0438\u043c\u0435\u043d\u043d\u043e \u043f\u043e \u043f\u043e\u0440\u044f\u0434\u043a\u0443?","\u0412\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u0435\u0434\u0435\u043d\u0438\u0435 \u043f\u043e \u043f\u043e\u0440\u044f\u0434\u043a\u0443 \u0438 \u0434\u0435\u043b\u0430\u0435\u0442 \u044d\u0442\u043e \u043d\u0430\u0441\u0442\u043e\u044f\u0449\u0438\u043c \u0442\u0435\u0441\u0442\u043e\u043c \u0440\u0430\u0431\u043e\u0447\u0435\u0439 \u043f\u0430\u043c\u044f\u0442\u0438, \u0430 \u043d\u0435 \u043f\u0440\u043e\u0441\u0442\u044b\u043c \u0443\u0437\u043d\u0430\u0432\u0430\u043d\u0438\u0435\u043c. \u0421\u043e\u0445\u0440\u0430\u043d\u0438\u0442\u044c \u043f\u043e\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c \u043f\u043e\u0434 \u043f\u043e\u043c\u0435\u0445\u0430\u043c\u0438 \u2014 \u0438 \u0435\u0441\u0442\u044c \u0442\u043e\u0442 \u043d\u0430\u0432\u044b\u043a, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u0438\u0437\u043c\u0435\u0440\u044f\u0435\u0442\u0441\u044f \u0438 \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442\u0441\u044f."]],variants:"\u0411\u043b\u0438\u0437\u043a\u0430\u044f \u0440\u043e\u0434\u043d\u044f \u0437\u0430\u043c\u0435\u043d\u044f\u0435\u0442 \u0441\u0447\u0451\u0442 \u043f\u0440\u0435\u0434\u043b\u043e\u0436\u0435\u043d\u0438\u044f\u043c\u0438, \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u043d\u0443\u0436\u043d\u043e \u043e\u0446\u0435\u043d\u0438\u0442\u044c \u043d\u0430 \u043e\u0441\u043c\u044b\u0441\u043b\u0435\u043d\u043d\u043e\u0441\u0442\u044c (reading span), \u0438\u043b\u0438 \u0441\u0443\u0436\u0434\u0435\u043d\u0438\u044f\u043c\u0438 \u043e \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0439 \u0441\u0438\u043c\u043c\u0435\u0442\u0440\u0438\u0438 (symmetry span); \u0437\u0430\u043f\u043e\u043c\u0438\u043d\u0430\u0442\u044c \u043c\u043e\u0436\u043d\u043e \u0431\u0443\u043a\u0432\u044b, \u0446\u0438\u0444\u0440\u044b \u0438\u043b\u0438 \u043f\u043e\u0437\u0438\u0446\u0438\u0438. \u041d\u0435\u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u0432\u0435\u0440\u0441\u0438\u0438 \u043f\u043e\u0434\u0441\u0442\u0440\u0430\u0438\u0432\u0430\u044e\u0442 \u0434\u043b\u0438\u043d\u0443 \u043d\u0430\u0431\u043e\u0440\u0430 \u043f\u043e\u0434 \u0432\u0430\u0448 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442, \u0430 \u0438\u0441\u0445\u043e\u0434\u043d\u0430\u044f \u043b\u0430\u0431\u043e\u0440\u0430\u0442\u043e\u0440\u043d\u0430\u044f \u0437\u0430\u0434\u0430\u0447\u0430 \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u043b\u0430 \u0441\u043b\u043e\u0432\u0430, \u0430 \u043d\u0435 \u043e\u0442\u0434\u0435\u043b\u044c\u043d\u044b\u0435 \u0431\u0443\u043a\u0432\u044b."},en:{about:"OSpan interleaves two jobs: you read a simple arithmetic equation and judge whether it is correct, then a single letter flashes that you must hold in mind. After a short run of these math-then-letter steps you recall the letters in the exact order they appeared. The point is to keep memorising while a distracting task keeps trying to push the letters out of your head.",benefit:"It loads working memory capacity, specifically the ability to hold a list of items while a second task competes for attention. That juggling of storage and processing at the same time is what the exercise stresses, along with resistance to interference.",history:"It began in 1989 as a laboratory yardstick for working memory, not as a game, and became one of the most cited complex span tasks in cognitive psychology. In 2005 Unsworth, Heitz, Schrock and Engle released an automated, mouse-driven version that scored itself, which made it spread well beyond the original lab into hundreds of studies and, later, into brain-training apps.",creator:"Created by Marilyn Turner and Randall (Randy) Engle in 1989, then at the University of South Carolina, as a measure of working memory capacity. The widely used automated version was built by Nash Unsworth, Richard Heitz, Josef Schrock and Randall Engle in 2005.",methods:"Lock in the recall order first by silently rehearsing the growing letter string in a steady rhythm, then snap fully onto each equation and back. Do not let the math become an excuse to drop a letter, and do not slow the math down so much that you are really just memorising in the gaps. Push set length up only when your recall is reliable, not when it merely feels easy.",duration:"Short, focused blocks work best: around 10 to 15 minutes, a few times a week. Stop when accuracy starts sliding, because tired, sloppy reps train bad habits rather than capacity.",research:"Evidence is strongest for exactly what you would expect, you get better at OSpan and at closely similar complex span tasks. As a measurement tool it reliably predicts fluid intelligence, but that is a correlation, not proof that drilling it raises your intelligence. When researchers actually trained people on complex span, Harrison and colleagues (2013) found gains transferred to other span tasks but not to fluid intelligence, and Redick and colleagues (2013) found no broad transfer at all, so treat claims about boosting IQ or general brainpower with caution.",rec:"Treat the equations as a genuine gatekeeper, answer each one honestly and quickly, rather than coasting through them to protect the letters.",faq:[["Is the arithmetic supposed to be hard?","No. The equations are deliberately easy. They exist to occupy and distract you, not to test your math, so the challenge lives in holding the letters while you process them."],["Will this make me smarter overall?","Honestly, probably not in a broad sense. You will get clearly better at this task and similar memory-span tasks, but controlled studies have generally failed to show transfer to fluid intelligence or everyday thinking."],["Why do I have to recall the letters in order?","Order recall is what makes it a true working memory test rather than simple recognition. Keeping the sequence intact under interference is the whole skill being measured and trained."]],variants:"Close relatives swap the math for sentences you must judge as sensible (reading span) or for spatial symmetry judgements (symmetry span); the to-be-remembered items can be letters, digits or locations. Some versions adapt the set length to your performance, and the original lab task used words rather than single letters."},es:{about:"OSpan entrelaza dos tareas: lees una ecuaci\xf3n aritm\xe9tica sencilla y juzgas si es correcta, y luego parpadea una sola letra que debes retener en la mente. Tras una breve serie de estos pasos de matem\xe1tica-y-luego-letra, recuerdas las letras en el orden exacto en que aparecieron. La clave es seguir memorizando mientras una tarea distractora intenta sin parar expulsar las letras de tu cabeza.",benefit:"Pone a trabajar la capacidad de la memoria de trabajo, en concreto la habilidad de retener una lista de elementos mientras una segunda tarea compite por la atenci\xf3n. Ese malabarismo simult\xe1neo de almacenamiento y procesamiento es lo que el ejercicio exige, junto con la resistencia a la interferencia.",history:"Empez\xf3 en 1989 como una vara de medir de laboratorio de la memoria de trabajo, no como un juego, y se convirti\xf3 en una de las tareas de amplitud compleja m\xe1s citadas de la psicolog\xeda cognitiva. En 2005, Unsworth, Heitz, Schrock y Engle publicaron una versi\xf3n automatizada, manejada con rat\xf3n, que se puntuaba a s\xed misma, lo que la hizo extenderse mucho m\xe1s all\xe1 del laboratorio original hacia cientos de estudios y, m\xe1s tarde, hacia las aplicaciones de entrenamiento cerebral.",creator:"Creada por Marilyn Turner y Randall (Randy) Engle en 1989, entonces en la Universidad de Carolina del Sur, como medida de la capacidad de la memoria de trabajo. La versi\xf3n automatizada de uso extendido fue construida por Nash Unsworth, Richard Heitz, Josef Schrock y Randall Engle en 2005.",methods:"Fija primero el orden de recuerdo repasando en silencio, con un ritmo constante, la cadena creciente de letras; luego eng\xe1nchate por completo a cada ecuaci\xf3n y vuelve. No dejes que las matem\xe1ticas se conviertan en una excusa para soltar una letra, y no ralentices tanto las matem\xe1ticas que en realidad solo est\xe9s memorizando en los huecos. Sube la longitud del conjunto solo cuando tu recuerdo sea fiable, no cuando simplemente te resulte f\xe1cil.",duration:"Los bloques cortos y concentrados funcionan mejor: alrededor de 10 a 15 minutos, varias veces por semana. Para cuando la precisi\xf3n empiece a caer, porque las repeticiones cansadas y descuidadas entrenan malos h\xe1bitos en vez de capacidad.",research:"La evidencia es m\xe1s s\xf3lida justo en lo que cabr\xeda esperar: mejoras en OSpan y en tareas de amplitud compleja muy parecidas. Como herramienta de medici\xf3n predice de forma fiable la inteligencia fluida, pero eso es una correlaci\xf3n, no una prueba de que machacarla eleve tu inteligencia. Cuando los investigadores entrenaron de verdad a personas en amplitud compleja, Harrison y colaboradores (2013) hallaron que las mejoras se transfer\xedan a otras tareas de amplitud pero no a la inteligencia fluida, y Redick y colaboradores (2013) no encontraron transferencia amplia alguna, as\xed que toma con cautela las afirmaciones sobre aumentar el CI o la potencia cerebral general.",rec:"Trata las ecuaciones como un aut\xe9ntico guardi\xe1n de la puerta: responde cada una con honestidad y rapidez, en lugar de pasar de largo por ellas para proteger las letras.",faq:[["\xbfSe supone que la aritm\xe9tica debe ser dif\xedcil?","No. Las ecuaciones son deliberadamente f\xe1ciles. Existen para ocuparte y distraerte, no para evaluar tus matem\xe1ticas, as\xed que el reto reside en retener las letras mientras las procesas."],["\xbfEsto me har\xe1 m\xe1s inteligente en general?","Honestamente, probablemente no en un sentido amplio. Mejorar\xe1s claramente en esta tarea y en tareas similares de amplitud de memoria, pero los estudios controlados, por lo general, no han logrado mostrar transferencia a la inteligencia fluida ni al pensamiento cotidiano."],["\xbfPor qu\xe9 tengo que recordar las letras en orden?","El recuerdo en orden es lo que la convierte en una verdadera prueba de memoria de trabajo y no en simple reconocimiento. Mantener la secuencia intacta bajo interferencia es toda la habilidad que se mide y se entrena."]],variants:"Sus parientes cercanos cambian las matem\xe1ticas por frases que debes juzgar como sensatas (amplitud de lectura) o por juicios de simetr\xeda espacial (amplitud de simetr\xeda); los elementos a recordar pueden ser letras, d\xedgitos o ubicaciones. Algunas versiones adaptan la longitud del conjunto a tu rendimiento, y la tarea original de laboratorio usaba palabras en lugar de letras sueltas."},de:{about:"OSpan verschachtelt zwei Aufgaben: Du liest eine einfache Rechengleichung und beurteilst, ob sie stimmt, dann blitzt ein einzelner Buchstabe auf, den du dir merken musst. Nach einer kurzen Folge dieser Rechnen-dann-Buchstabe-Schritte gibst du die Buchstaben in genau der Reihenfolge wieder, in der sie erschienen sind. Der Sinn liegt darin, weiter zu merken, w\xe4hrend eine ablenkende Aufgabe st\xe4ndig versucht, die Buchstaben aus deinem Kopf zu verdr\xe4ngen.",benefit:"Es belastet die Kapazit\xe4t des Arbeitsged\xe4chtnisses, konkret die F\xe4higkeit, eine Liste von Elementen festzuhalten, w\xe4hrend eine zweite Aufgabe um die Aufmerksamkeit konkurriert. Genau dieses gleichzeitige Jonglieren von Speichern und Verarbeiten fordert die \xdcbung, neben der Widerstandsf\xe4higkeit gegen Interferenz.",history:"Es begann 1989 als labortauglicher Ma\xdfstab f\xfcr das Arbeitsged\xe4chtnis, nicht als Spiel, und wurde zu einer der meistzitierten komplexen Span-Aufgaben der kognitiven Psychologie. 2005 ver\xf6ffentlichten Unsworth, Heitz, Schrock und Engle eine automatisierte, mausgesteuerte Version, die sich selbst auswertete, wodurch sie sich weit \xfcber das urspr\xfcngliche Labor hinaus in Hunderte von Studien und sp\xe4ter in Gehirntrainings-Apps verbreitete.",creator:"Entwickelt von Marilyn Turner und Randall (Randy) Engle im Jahr 1989, damals an der University of South Carolina, als Ma\xdf f\xfcr die Kapazit\xe4t des Arbeitsged\xe4chtnisses. Die weit verbreitete automatisierte Version wurde 2005 von Nash Unsworth, Richard Heitz, Josef Schrock und Randall Engle erstellt.",methods:"Lege zuerst die Wiedergabereihenfolge fest, indem du die wachsende Buchstabenkette in gleichm\xe4\xdfigem Rhythmus still wiederholst, und schalte dann vollst\xe4ndig auf jede Gleichung und wieder zur\xfcck. Lass die Rechnung nicht zur Ausrede werden, einen Buchstaben fallen zu lassen, und verlangsame die Rechnung nicht so sehr, dass du in Wahrheit nur in den L\xfccken auswendig lernst. Erh\xf6he die Set-L\xe4nge erst, wenn deine Wiedergabe zuverl\xe4ssig ist, nicht nur, wenn es sich leicht anf\xfchlt.",duration:"Kurze, konzentrierte Bl\xf6cke funktionieren am besten: rund 10 bis 15 Minuten, ein paar Mal pro Woche. H\xf6re auf, sobald die Genauigkeit nachl\xe4sst, denn m\xfcde, schludrige Wiederholungen trainieren schlechte Gewohnheiten statt Kapazit\xe4t.",research:"Am st\xe4rksten ist die Beleglage genau f\xfcr das, was man erwarten w\xfcrde: Du wirst in OSpan und in eng verwandten komplexen Span-Aufgaben besser. Als Messinstrument sagt es die fluide Intelligenz zuverl\xe4ssig vorher, doch das ist eine Korrelation, kein Beweis, dass das \xdcben deine Intelligenz steigert. Als Forscher Menschen tats\xe4chlich im komplexen Span trainierten, fanden Harrison und Kollegen (2013), dass sich die Zugewinne auf andere Span-Aufgaben \xfcbertrugen, aber nicht auf die fluide Intelligenz, und Redick und Kollegen (2013) fanden gar keinen breiten Transfer \u2013 nimm Behauptungen \xfcber die Steigerung von IQ oder allgemeiner Geisteskraft also mit Vorsicht.",rec:"Behandle die Gleichungen als echten T\xfcrsteher, beantworte jede ehrlich und z\xfcgig, statt sie nur zu \xfcberfliegen, um die Buchstaben zu sch\xfctzen.",faq:[["Soll die Rechnung schwer sein?","Nein. Die Gleichungen sind absichtlich leicht. Sie sind dazu da, dich zu besch\xe4ftigen und abzulenken, nicht um deine Mathekenntnisse zu pr\xfcfen \u2013 die Herausforderung liegt also darin, die Buchstaben zu behalten, w\xe4hrend du sie verarbeitest."],["Macht mich das insgesamt kl\xfcger?","Ehrlich gesagt wahrscheinlich nicht im breiten Sinn. Du wirst in dieser Aufgabe und in \xe4hnlichen Merkspannen-Aufgaben deutlich besser, aber kontrollierte Studien konnten einen Transfer auf die fluide Intelligenz oder das allt\xe4gliche Denken meist nicht nachweisen."],["Warum muss ich die Buchstaben in Reihenfolge wiedergeben?","Die Reihenfolge-Wiedergabe macht daraus einen echten Arbeitsged\xe4chtnistest statt eines blo\xdfen Wiedererkennens. Die Abfolge unter Interferenz intakt zu halten, ist genau die F\xe4higkeit, die gemessen und trainiert wird."]],variants:"Nahe Verwandte tauschen die Rechnung gegen S\xe4tze, die du als sinnvoll beurteilen musst (Reading Span), oder gegen r\xe4umliche Symmetrieurteile (Symmetry Span); die zu merkenden Elemente k\xf6nnen Buchstaben, Ziffern oder Orte sein. Manche Versionen passen die Set-L\xe4nge an deine Leistung an, und die urspr\xfcngliche Laboraufgabe verwendete W\xf6rter statt einzelner Buchstaben."},pt:{about:"O OSpan intercala duas tarefas: voc\xea l\xea uma equa\xe7\xe3o aritm\xe9tica simples e julga se est\xe1 correta e, em seguida, aparece por um instante uma \xfanica letra que voc\xea precisa guardar na cabe\xe7a. Depois de uma curta sequ\xeancia desses passos matem\xe1tica-e-depois-letra, voc\xea recorda as letras na ordem exata em que apareceram. O objetivo \xe9 continuar memorizando enquanto uma tarefa distratora insiste em empurrar as letras para fora da sua mente.",benefit:"Ele sobrecarrega a capacidade da mem\xf3ria de trabalho, especificamente a habilidade de reter uma lista de itens enquanto uma segunda tarefa disputa a aten\xe7\xe3o. Esse malabarismo de armazenar e processar ao mesmo tempo \xe9 o que o exerc\xedcio exige, junto com a resist\xeancia \xe0 interfer\xeancia.",history:"Come\xe7ou em 1989 como uma r\xe9gua de laborat\xf3rio para a mem\xf3ria de trabalho, e n\xe3o como jogo, e tornou-se uma das tarefas de span complexo mais citadas da psicologia cognitiva. Em 2005, Unsworth, Heitz, Schrock e Engle lan\xe7aram uma vers\xe3o automatizada, comandada pelo mouse, que se pontuava sozinha, o que a fez se espalhar muito al\xe9m do laborat\xf3rio original, alcan\xe7ando centenas de estudos e, mais tarde, aplicativos de treino cerebral.",creator:"Criado por Marilyn Turner e Randall (Randy) Engle em 1989, ent\xe3o na Universidade da Carolina do Sul, como medida da capacidade da mem\xf3ria de trabalho. A vers\xe3o automatizada amplamente usada foi constru\xedda por Nash Unsworth, Richard Heitz, Josef Schrock e Randall Engle em 2005.",methods:"Fixe primeiro a ordem de recorda\xe7\xe3o ensaiando em sil\xeancio a cadeia crescente de letras num ritmo constante, e ent\xe3o mude o foco totalmente para cada equa\xe7\xe3o e volte. N\xe3o deixe a matem\xe1tica virar desculpa para perder uma letra, e n\xe3o desacelere tanto a matem\xe1tica a ponto de, na pr\xe1tica, estar s\xf3 memorizando nos intervalos. S\xf3 aumente o tamanho do conjunto quando a sua recorda\xe7\xe3o estiver confi\xe1vel, n\xe3o quando apenas parecer f\xe1cil.",duration:"Blocos curtos e concentrados funcionam melhor: por volta de 10 a 15 minutos, algumas vezes por semana. Pare quando a precis\xe3o come\xe7ar a cair, porque repeti\xe7\xf5es cansadas e desleixadas treinam maus h\xe1bitos, e n\xe3o capacidade.",research:"As evid\xeancias s\xe3o mais fortes exatamente para o que se espera: voc\xea fica melhor no OSpan e em tarefas de span complexo bem parecidas. Como ferramenta de medida, ele prev\xea de forma confi\xe1vel a intelig\xeancia fluida, mas isso \xe9 uma correla\xe7\xe3o, n\xe3o prova de que trein\xe1-lo aumenta a sua intelig\xeancia. Quando os pesquisadores de fato treinaram pessoas em span complexo, Harrison e colegas (2013) constataram que os ganhos se transferiram para outras tarefas de span, mas n\xe3o para a intelig\xeancia fluida, e Redick e colegas (2013) n\xe3o encontraram transfer\xeancia ampla nenhuma, ent\xe3o encare com cautela as alega\xe7\xf5es de aumentar o QI ou a capacidade cerebral geral.",rec:"Trate as equa\xe7\xf5es como um verdadeiro porteiro, respondendo cada uma com honestidade e rapidez, em vez de passar por elas de qualquer jeito s\xf3 para proteger as letras.",faq:[["A aritm\xe9tica \xe9 para ser dif\xedcil?","N\xe3o. As equa\xe7\xf5es s\xe3o propositalmente f\xe1ceis. Elas existem para ocupar e distrair voc\xea, n\xe3o para testar a sua matem\xe1tica, ent\xe3o o desafio est\xe1 em reter as letras enquanto voc\xea as processa."],["Isso vai me deixar mais inteligente no geral?","Honestamente, provavelmente n\xe3o num sentido amplo. Voc\xea vai ficar claramente melhor nesta tarefa e em tarefas semelhantes de span de mem\xf3ria, mas estudos controlados em geral n\xe3o conseguiram mostrar transfer\xeancia para a intelig\xeancia fluida ou para o pensamento do dia a dia."],["Por que tenho de recordar as letras em ordem?","A recorda\xe7\xe3o em ordem \xe9 o que faz disso um verdadeiro teste de mem\xf3ria de trabalho, e n\xe3o simples reconhecimento. Manter a sequ\xeancia intacta sob interfer\xeancia \xe9 toda a habilidade que est\xe1 sendo medida e treinada."]],variants:"Parentes pr\xf3ximos trocam a matem\xe1tica por frases que voc\xea deve julgar como sensatas ou n\xe3o (reading span) ou por julgamentos de simetria espacial (symmetry span); os itens a recordar podem ser letras, d\xedgitos ou posi\xe7\xf5es. Algumas vers\xf5es adaptam o tamanho do conjunto ao seu desempenho, e a tarefa de laborat\xf3rio original usava palavras em vez de letras isoladas."},hi:{about:"OSpan \u0926\u094b \u0915\u093e\u092e\u094b\u0902 \u0915\u094b \u0906\u092a\u0938 \u092e\u0947\u0902 \u0917\u0942\u0901\u0925 \u0926\u0947\u0924\u093e \u0939\u0948: \u0906\u092a \u090f\u0915 \u0938\u0930\u0932 \u0905\u0902\u0915\u0917\u0923\u093f\u0924\u0940\u092f \u0938\u092e\u0940\u0915\u0930\u0923 \u092a\u0922\u093c\u0924\u0947 \u0939\u0948\u0902 \u0914\u0930 \u0924\u092f \u0915\u0930\u0924\u0947 \u0939\u0948\u0902 \u0915\u093f \u0935\u0939 \u0938\u0939\u0940 \u0939\u0948 \u092f\u093e \u0928\u0939\u0940\u0902, \u092b\u093f\u0930 \u090f\u0915 \u0905\u0915\u0947\u0932\u093e \u0905\u0915\u094d\u0937\u0930 \u091a\u092e\u0915\u0924\u093e \u0939\u0948 \u091c\u093f\u0938\u0947 \u0906\u092a\u0915\u094b \u092e\u0928 \u092e\u0947\u0902 \u0925\u093e\u092e\u0947 \u0930\u0916\u0928\u093e \u0939\u094b\u0924\u093e \u0939\u0948\u0964 \u0910\u0938\u0947 \u0917\u0923\u093f\u0924-\u092b\u093f\u0930-\u0905\u0915\u094d\u0937\u0930 \u0935\u093e\u0932\u0947 \u0915\u0941\u091b \u091a\u0930\u0923\u094b\u0902 \u0915\u0947 \u091b\u094b\u091f\u0947 \u0926\u094c\u0930 \u0915\u0947 \u092c\u093e\u0926 \u0906\u092a \u0905\u0915\u094d\u0937\u0930\u094b\u0902 \u0915\u094b \u0920\u0940\u0915 \u0909\u0938\u0940 \u0915\u094d\u0930\u092e \u092e\u0947\u0902 \u092f\u093e\u0926 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902 \u091c\u093f\u0938\u092e\u0947\u0902 \u0935\u0947 \u0906\u090f \u0925\u0947\u0964 \u092a\u0942\u0930\u0940 \u092c\u093e\u0924 \u092f\u0939 \u0939\u0948 \u0915\u093f \u092f\u093e\u0926 \u0915\u0930\u0924\u0947 \u0930\u0939\u093f\u090f \u091c\u092c\u0915\u093f \u090f\u0915 \u092d\u091f\u0915\u093e\u0928\u0947 \u0935\u093e\u0932\u093e \u0915\u093e\u092e \u0932\u0917\u093e\u0924\u093e\u0930 \u0905\u0915\u094d\u0937\u0930\u094b\u0902 \u0915\u094b \u0906\u092a\u0915\u0947 \u0926\u093f\u092e\u093e\u0917 \u0938\u0947 \u092c\u093e\u0939\u0930 \u0927\u0915\u0947\u0932\u0928\u0947 \u0915\u0940 \u0915\u094b\u0936\u093f\u0936 \u0915\u0930\u0924\u093e \u0930\u0939\u0924\u093e \u0939\u0948\u0964",benefit:"\u092f\u0939 \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932 \u0938\u094d\u092e\u0943\u0924\u093f \u0915\u0940 \u0915\u094d\u0937\u092e\u0924\u093e \u092a\u0930 \u092c\u094b\u091d \u0921\u093e\u0932\u0924\u093e \u0939\u0948, \u0916\u093c\u093e\u0938\u0915\u0930 \u0909\u0938 \u0915\u094d\u0937\u092e\u0924\u093e \u092a\u0930 \u091c\u094b \u091a\u0940\u091c\u093c\u094b\u0902 \u0915\u0940 \u090f\u0915 \u0938\u0942\u091a\u0940 \u0915\u094b \u0925\u093e\u092e\u0947 \u0930\u0916\u0924\u0940 \u0939\u0948 \u091c\u092c\u0915\u093f \u090f\u0915 \u0926\u0942\u0938\u0930\u093e \u0915\u093e\u092e \u0927\u094d\u092f\u093e\u0928 \u0915\u0947 \u0932\u093f\u090f \u0939\u094b\u0921\u093c \u0915\u0930\u0924\u093e \u0939\u0948\u0964 \u092d\u0902\u0921\u093e\u0930\u0923 \u0914\u0930 \u0938\u0902\u0938\u093e\u0927\u0928 \u0915\u0940 \u092f\u0939\u0940 \u090f\u0915-\u0938\u093e\u0925 \u092c\u093e\u091c\u093c\u0940\u0917\u0930\u0940 \u0907\u0938 \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u093e \u0926\u092c\u093e\u0935-\u092c\u093f\u0902\u0926\u0941 \u0939\u0948, \u0938\u093e\u0925 \u0939\u0940 \u0926\u0916\u093c\u0932 \u0915\u0947 \u092a\u094d\u0930\u0924\u093f \u092a\u094d\u0930\u0924\u093f\u0930\u094b\u0927 \u092d\u0940\u0964",history:"\u0907\u0938\u0915\u0940 \u0936\u0941\u0930\u0941\u0906\u0924 1989 \u092e\u0947\u0902 \u090f\u0915 \u0916\u0947\u0932 \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u0928\u0939\u0940\u0902, \u092c\u0932\u094d\u0915\u093f \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932 \u0938\u094d\u092e\u0943\u0924\u093f \u0915\u0947 \u090f\u0915 \u092a\u094d\u0930\u092f\u094b\u0917\u0936\u093e\u0932\u093e \u092a\u0948\u092e\u093e\u0928\u0947 \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u0939\u0941\u0908, \u0914\u0930 \u092f\u0939 \u0938\u0902\u091c\u094d\u091e\u093e\u0928\u093e\u0924\u094d\u092e\u0915 \u092e\u0928\u094b\u0935\u093f\u091c\u094d\u091e\u093e\u0928 \u0915\u0947 \u0938\u092c\u0938\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0909\u0926\u094d\u0927\u0943\u0924 \u091c\u091f\u093f\u0932 span \u0915\u093e\u0930\u094d\u092f\u094b\u0902 \u092e\u0947\u0902 \u0938\u0947 \u090f\u0915 \u092c\u0928 \u0917\u092f\u093e\u0964 2005 \u092e\u0947\u0902 Unsworth, Heitz, Schrock \u0914\u0930 Engle \u0928\u0947 \u090f\u0915 \u0938\u094d\u0935\u091a\u093e\u0932\u093f\u0924, \u092e\u093e\u0909\u0938-\u091a\u093e\u0932\u093f\u0924 \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u091c\u093e\u0930\u0940 \u0915\u093f\u092f\u093e \u091c\u094b \u0916\u093c\u0941\u0926 \u0939\u0940 \u0938\u094d\u0915\u094b\u0930 \u0928\u093f\u0915\u093e\u0932\u0924\u093e \u0925\u093e, \u091c\u093f\u0938\u0915\u0947 \u091a\u0932\u0924\u0947 \u092f\u0939 \u092e\u0942\u0932 \u092a\u094d\u0930\u092f\u094b\u0917\u0936\u093e\u0932\u093e \u0938\u0947 \u0915\u0939\u0940\u0902 \u0906\u0917\u0947 \u0938\u0948\u0915\u0921\u093c\u094b\u0902 \u0905\u0927\u094d\u092f\u092f\u0928\u094b\u0902 \u092e\u0947\u0902 \u0914\u0930 \u092c\u093e\u0926 \u092e\u0947\u0902 \u0926\u093f\u092e\u093e\u0917\u0940-\u0915\u0938\u0930\u0924 \u0915\u0947 \u0910\u092a\u094d\u0938 \u092e\u0947\u0902 \u092d\u0940 \u092b\u0948\u0932 \u0917\u092f\u093e\u0964",creator:"\u0907\u0938\u0947 1989 \u092e\u0947\u0902 Marilyn Turner \u0914\u0930 Randall (Randy) Engle \u0928\u0947, \u0924\u092c University of South Carolina \u092e\u0947\u0902 \u0930\u0939\u0924\u0947 \u0939\u0941\u090f, \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932 \u0938\u094d\u092e\u0943\u0924\u093f \u0915\u0940 \u0915\u094d\u0937\u092e\u0924\u093e \u0915\u0940 \u090f\u0915 \u092e\u093e\u092a \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u092c\u0928\u093e\u092f\u093e \u0925\u093e\u0964 \u0935\u094d\u092f\u093e\u092a\u0915 \u0930\u0942\u092a \u0938\u0947 \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0939\u094b\u0928\u0947 \u0935\u093e\u0932\u093e \u0938\u094d\u0935\u091a\u093e\u0932\u093f\u0924 \u0938\u0902\u0938\u094d\u0915\u0930\u0923 2005 \u092e\u0947\u0902 Nash Unsworth, Richard Heitz, Josef Schrock \u0914\u0930 Randall Engle \u0928\u0947 \u092c\u0928\u093e\u092f\u093e\u0964",methods:"\u092a\u0939\u0932\u0947 \u092c\u0922\u093c\u0924\u0940 \u0939\u0941\u0908 \u0905\u0915\u094d\u0937\u0930-\u0936\u0943\u0902\u0916\u0932\u093e \u0915\u094b \u090f\u0915 \u0938\u094d\u0925\u093f\u0930 \u0932\u092f \u092e\u0947\u0902 \u092e\u0928-\u0939\u0940-\u092e\u0928 \u0926\u094b\u0939\u0930\u093e\u0915\u0930 \u092f\u093e\u0926 \u0915\u093e \u0915\u094d\u0930\u092e \u092a\u0915\u094d\u0915\u093e \u0915\u0930 \u0932\u0940\u091c\u093f\u090f, \u092b\u093f\u0930 \u092a\u0942\u0930\u0940 \u0924\u0930\u0939 \u0939\u0930 \u0938\u092e\u0940\u0915\u0930\u0923 \u092a\u0930 \u091c\u093e\u0907\u090f \u0914\u0930 \u0935\u093e\u092a\u0938 \u0906\u0907\u090f\u0964 \u0917\u0923\u093f\u0924 \u0915\u094b \u0915\u093f\u0938\u0940 \u0905\u0915\u094d\u0937\u0930 \u0915\u094b \u091b\u094b\u0921\u093c\u0928\u0947 \u0915\u093e \u092c\u0939\u093e\u0928\u093e \u092e\u0924 \u092c\u0928\u0928\u0947 \u0926\u0940\u091c\u093f\u090f, \u0914\u0930 \u0917\u0923\u093f\u0924 \u0915\u094b \u0907\u0924\u0928\u093e \u0927\u0940\u092e\u093e \u092d\u0940 \u092e\u0924 \u0915\u0940\u091c\u093f\u090f \u0915\u093f \u0905\u0938\u0932 \u092e\u0947\u0902 \u0906\u092a \u092c\u0938 \u092c\u0940\u091a \u0915\u0947 \u0905\u0902\u0924\u0930\u093e\u0932\u094b\u0902 \u092e\u0947\u0902 \u092f\u093e\u0926 \u0915\u0930 \u0930\u0939\u0947 \u0939\u094b\u0902\u0964 \u0938\u0947\u091f \u0915\u0940 \u0932\u0902\u092c\u093e\u0908 \u0924\u092d\u0940 \u092c\u0922\u093c\u093e\u0907\u090f \u091c\u092c \u0906\u092a\u0915\u0940 \u092f\u093e\u0926 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0939\u094b, \u0928 \u0915\u093f \u0938\u093f\u0930\u094d\u092b\u093c \u0924\u092c \u091c\u092c \u0935\u0939 \u0906\u0938\u093e\u0928 \u092e\u0939\u0938\u0942\u0938 \u0939\u094b\u0964",duration:"\u091b\u094b\u091f\u0947, \u090f\u0915\u093e\u0917\u094d\u0930 \u0916\u0902\u0921 \u0938\u092c\u0938\u0947 \u0905\u091a\u094d\u091b\u0947 \u0930\u0939\u0924\u0947 \u0939\u0948\u0902: \u0915\u0930\u0940\u092c 10 \u0938\u0947 15 \u092e\u093f\u0928\u091f, \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u0915\u0941\u091b \u092c\u093e\u0930\u0964 \u091c\u092c \u0938\u091f\u0940\u0915\u0924\u093e \u0917\u093f\u0930\u0928\u0947 \u0932\u0917\u0947 \u0924\u092c \u0930\u0941\u0915 \u091c\u093e\u0907\u090f, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u0925\u0915\u0947 \u0939\u0941\u090f, \u0932\u093e\u092a\u0930\u0935\u093e\u0939 \u0926\u094b\u0939\u0930\u093e\u0935 \u0915\u094d\u0937\u092e\u0924\u093e \u0915\u0947 \u092c\u091c\u093e\u092f \u092c\u0941\u0930\u0940 \u0906\u0926\u0924\u0947\u0902 \u0938\u0927\u093e\u0924\u0947 \u0939\u0948\u0902\u0964",research:"\u0938\u092c\u0938\u0947 \u092a\u0941\u0916\u093c\u094d\u0924\u093e \u0938\u092c\u0942\u0924 \u0920\u0940\u0915 \u0909\u0938\u0940 \u092c\u093e\u0924 \u0915\u0947 \u0932\u093f\u090f \u0939\u0948 \u091c\u093f\u0938\u0915\u0940 \u0906\u092a \u0909\u092e\u094d\u092e\u0940\u0926 \u0915\u0930\u0947\u0902\u0917\u0947 \u2014 \u0906\u092a OSpan \u092e\u0947\u0902 \u0914\u0930 \u0907\u0938\u0938\u0947 \u092c\u0947\u0939\u0926 \u092e\u093f\u0932\u0924\u0947-\u091c\u0941\u0932\u0924\u0947 \u091c\u091f\u093f\u0932 span \u0915\u093e\u0930\u094d\u092f\u094b\u0902 \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902\u0964 \u090f\u0915 \u092e\u093e\u092a-\u0909\u092a\u0915\u0930\u0923 \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u092f\u0939 \u0924\u0930\u0932 \u092c\u0941\u0926\u094d\u0927\u093f \u0915\u0940 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u092d\u0935\u093f\u0937\u094d\u092f\u0935\u093e\u0923\u0940 \u0915\u0930\u0924\u093e \u0939\u0948, \u092a\u0930 \u092f\u0939 \u090f\u0915 \u0938\u0939\u0938\u0902\u092c\u0902\u0927 \u0939\u0948, \u0907\u0938 \u092c\u093e\u0924 \u0915\u093e \u0938\u092c\u0942\u0924 \u0928\u0939\u0940\u0902 \u0915\u093f \u0907\u0938\u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0906\u092a\u0915\u0940 \u092c\u0941\u0926\u094d\u0927\u093f \u092c\u0922\u093c\u093e\u0924\u093e \u0939\u0948\u0964 \u091c\u092c \u0936\u094b\u0927\u0915\u0930\u094d\u0924\u093e\u0913\u0902 \u0928\u0947 \u0938\u091a\u092e\u0941\u091a \u0932\u094b\u0917\u094b\u0902 \u0915\u094b \u091c\u091f\u093f\u0932 span \u092a\u0930 \u091f\u094d\u0930\u0947\u0928\u093f\u0902\u0917 \u0926\u0940, \u0924\u094b Harrison \u0914\u0930 \u0938\u0939\u092f\u094b\u0917\u093f\u092f\u094b\u0902 (2013) \u0928\u0947 \u092a\u093e\u092f\u093e \u0915\u093f \u0932\u093e\u092d \u0926\u0942\u0938\u0930\u0947 span \u0915\u093e\u0930\u094d\u092f\u094b\u0902 \u0924\u0915 \u0924\u094b \u092a\u0939\u0941\u0901\u091a\u0947 \u092a\u0930 \u0924\u0930\u0932 \u092c\u0941\u0926\u094d\u0927\u093f \u0924\u0915 \u0928\u0939\u0940\u0902, \u0914\u0930 Redick \u0914\u0930 \u0938\u0939\u092f\u094b\u0917\u093f\u092f\u094b\u0902 (2013) \u0928\u0947 \u092a\u093e\u092f\u093e \u0915\u093f \u0915\u094b\u0908 \u0935\u094d\u092f\u093e\u092a\u0915 \u091f\u094d\u0930\u093e\u0902\u0938\u092b\u093c\u0930 \u0939\u0941\u0906 \u0939\u0940 \u0928\u0939\u0940\u0902, \u0907\u0938\u0932\u093f\u090f IQ \u092f\u093e \u0906\u092e \u0926\u093f\u092e\u093e\u0917\u0940 \u0924\u093e\u0915\u093c\u0924 \u092c\u0922\u093c\u093e\u0928\u0947 \u0915\u0947 \u0926\u093e\u0935\u094b\u0902 \u0915\u094b \u0938\u093e\u0935\u0927\u093e\u0928\u0940 \u0938\u0947 \u0932\u0940\u091c\u093f\u090f\u0964",rec:"\u0938\u092e\u0940\u0915\u0930\u0923\u094b\u0902 \u0915\u094b \u090f\u0915 \u0938\u091a\u094d\u091a\u093e \u0926\u094d\u0935\u093e\u0930\u092a\u093e\u0932 \u092e\u093e\u0928\u093f\u090f, \u0939\u0930 \u090f\u0915 \u0915\u093e \u091c\u0935\u093e\u092c \u0908\u092e\u093e\u0928\u0926\u093e\u0930\u0940 \u0914\u0930 \u0924\u0947\u091c\u093c\u0940 \u0938\u0947 \u0926\u0940\u091c\u093f\u090f, \u0928 \u0915\u093f \u0905\u0915\u094d\u0937\u0930\u094b\u0902 \u0915\u094b \u092c\u091a\u093e\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0909\u0928\u094d\u0939\u0947\u0902 \u092f\u0942\u0901 \u0939\u0940 \u0938\u0930\u0915\u093e\u0924\u0947 \u0939\u0941\u090f \u0928\u093f\u0915\u0932\u093f\u090f\u0964",faq:[["\u0915\u094d\u092f\u093e \u0905\u0902\u0915\u0917\u0923\u093f\u0924 \u0915\u093e \u0915\u0920\u093f\u0928 \u0939\u094b\u0928\u093e \u091c\u093c\u0930\u0942\u0930\u0940 \u0939\u0948?","\u0928\u0939\u0940\u0902\u0964 \u0938\u092e\u0940\u0915\u0930\u0923 \u091c\u093e\u0928-\u092c\u0942\u091d\u0915\u0930 \u0906\u0938\u093e\u0928 \u0930\u0916\u0947 \u091c\u093e\u0924\u0947 \u0939\u0948\u0902\u0964 \u0935\u0947 \u0906\u092a\u0915\u094b \u0909\u0932\u091d\u093e\u0928\u0947 \u0914\u0930 \u092d\u091f\u0915\u093e\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0939\u094b\u0924\u0947 \u0939\u0948\u0902, \u0906\u092a\u0915\u0947 \u0917\u0923\u093f\u0924 \u0915\u094b \u092a\u0930\u0916\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0928\u0939\u0940\u0902, \u0907\u0938\u0932\u093f\u090f \u0905\u0938\u0932\u0940 \u091a\u0941\u0928\u094c\u0924\u0940 \u0905\u0915\u094d\u0937\u0930\u094b\u0902 \u0915\u094b \u0925\u093e\u092e\u0947 \u0930\u0916\u0928\u0947 \u092e\u0947\u0902 \u0939\u0948 \u091c\u092c\u0915\u093f \u0906\u092a \u0909\u0928\u094d\u0939\u0947\u0902 \u0938\u0902\u0938\u093e\u0927\u093f\u0924 \u0915\u0930 \u0930\u0939\u0947 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902\u0964"],["\u0915\u094d\u092f\u093e \u0907\u0938\u0938\u0947 \u092e\u0948\u0902 \u0915\u0941\u0932 \u092e\u093f\u0932\u093e\u0915\u0930 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0939\u094b\u0936\u093f\u092f\u093e\u0930 \u092c\u0928 \u091c\u093e\u090a\u0901\u0917\u093e?","\u0908\u092e\u093e\u0928\u0926\u093e\u0930\u0940 \u0938\u0947 \u0915\u0939\u0947\u0902 \u0924\u094b, \u0935\u094d\u092f\u093e\u092a\u0915 \u0905\u0930\u094d\u0925 \u092e\u0947\u0902 \u0936\u093e\u092f\u0926 \u0928\u0939\u0940\u0902\u0964 \u0906\u092a \u0907\u0938 \u0915\u093e\u092e \u092e\u0947\u0902 \u0914\u0930 \u0907\u0938\u0938\u0947 \u092e\u093f\u0932\u0924\u0947-\u091c\u0941\u0932\u0924\u0947 \u0938\u094d\u092e\u0943\u0924\u093f-span \u0915\u093e\u0930\u094d\u092f\u094b\u0902 \u092e\u0947\u0902 \u0938\u093e\u092b\u093c \u0924\u094c\u0930 \u092a\u0930 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u090f\u0901\u0917\u0947, \u092a\u0930 \u0928\u093f\u092f\u0902\u0924\u094d\u0930\u093f\u0924 \u0905\u0927\u094d\u092f\u092f\u0928 \u0906\u092e \u0924\u094c\u0930 \u092a\u0930 \u0924\u0930\u0932 \u092c\u0941\u0926\u094d\u0927\u093f \u092f\u093e \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0940 \u0938\u094b\u091a \u0924\u0915 \u091f\u094d\u0930\u093e\u0902\u0938\u092b\u093c\u0930 \u0926\u093f\u0916\u093e\u0928\u0947 \u092e\u0947\u0902 \u0928\u093e\u0915\u093e\u092e \u0930\u0939\u0947 \u0939\u0948\u0902\u0964"],["\u092e\u0941\u091d\u0947 \u0905\u0915\u094d\u0937\u0930\u094b\u0902 \u0915\u094b \u0915\u094d\u0930\u092e \u092e\u0947\u0902 \u0939\u0940 \u0915\u094d\u092f\u094b\u0902 \u092f\u093e\u0926 \u0915\u0930\u0928\u093e \u092a\u0921\u093c\u0924\u093e \u0939\u0948?","\u0915\u094d\u0930\u092e \u092e\u0947\u0902 \u092f\u093e\u0926 \u0915\u0930\u0928\u093e \u0939\u0940 \u0907\u0938\u0947 \u0938\u0930\u0932 \u092a\u0939\u091a\u093e\u0928 \u0915\u0947 \u092c\u091c\u093e\u092f \u090f\u0915 \u0938\u091a\u094d\u091a\u093e \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932-\u0938\u094d\u092e\u0943\u0924\u093f \u092a\u0930\u0940\u0915\u094d\u0937\u0923 \u092c\u0928\u093e\u0924\u093e \u0939\u0948\u0964 \u0926\u0916\u093c\u0932 \u0915\u0947 \u092c\u0940\u091a \u092d\u0940 \u0915\u094d\u0930\u092e \u0915\u094b \u092c\u0930\u0915\u0930\u093e\u0930 \u0930\u0916\u0928\u093e \u0939\u0940 \u0935\u0939 \u092a\u0942\u0930\u093e \u0915\u094c\u0936\u0932 \u0939\u0948 \u091c\u093f\u0938\u0947 \u092e\u093e\u092a\u093e \u0914\u0930 \u0938\u0927\u093e\u092f\u093e \u091c\u093e \u0930\u0939\u093e \u0939\u0948\u0964"]],variants:"\u0928\u091c\u093c\u0926\u0940\u0915\u0940 \u0930\u093f\u0936\u094d\u0924\u0947\u0926\u093e\u0930 \u0917\u0923\u093f\u0924 \u0915\u0940 \u091c\u0917\u0939 \u0910\u0938\u0947 \u0935\u093e\u0915\u094d\u092f \u0930\u0916 \u0926\u0947\u0924\u0947 \u0939\u0948\u0902 \u091c\u093f\u0928\u094d\u0939\u0947\u0902 \u0906\u092a\u0915\u094b \u0938\u092e\u091d\u0926\u093e\u0930\u0940 \u092d\u0930\u093e \u0906\u0901\u0915\u0928\u093e \u0939\u094b\u0924\u093e \u0939\u0948 (reading span) \u092f\u093e \u0938\u094d\u0925\u093e\u0928\u093f\u0915 \u0938\u092e\u0930\u0942\u092a\u0924\u093e \u0915\u0947 \u0928\u093f\u0930\u094d\u0923\u092f (symmetry span); \u092f\u093e\u0926 \u0930\u0916\u0940 \u091c\u093e\u0928\u0947 \u0935\u093e\u0932\u0940 \u091a\u0940\u091c\u093c\u0947\u0902 \u0905\u0915\u094d\u0937\u0930, \u0905\u0902\u0915 \u092f\u093e \u091c\u0917\u0939\u0947\u0902 \u0939\u094b \u0938\u0915\u0924\u0940 \u0939\u0948\u0902\u0964 \u0915\u0941\u091b \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0938\u0947\u091f \u0915\u0940 \u0932\u0902\u092c\u093e\u0908 \u0915\u094b \u0906\u092a\u0915\u0947 \u092a\u094d\u0930\u0926\u0930\u094d\u0936\u0928 \u0915\u0947 \u0939\u093f\u0938\u093e\u092c \u0938\u0947 \u0922\u093e\u0932 \u0932\u0947\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u092e\u0942\u0932 \u092a\u094d\u0930\u092f\u094b\u0917\u0936\u093e\u0932\u093e \u0915\u093e\u0930\u094d\u092f \u092e\u0947\u0902 \u0905\u0915\u0947\u0932\u0947 \u0905\u0915\u094d\u0937\u0930\u094b\u0902 \u0915\u0947 \u092c\u091c\u093e\u092f \u0936\u092c\u094d\u0926\u094b\u0902 \u0915\u093e \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0939\u094b\u0924\u093e \u0925\u093e\u0964"},zh:{about:"OSpan\uff08\u8fd0\u7b97\u5e7f\u5ea6\uff09\u628a\u4e24\u4ef6\u4e8b\u4ea4\u9519\u5728\u4e00\u8d77\uff1a\u4f60\u5148\u8bfb\u4e00\u9053\u7b80\u5355\u7684\u7b97\u5f0f\u5e76\u5224\u65ad\u5b83\u5bf9\u4e0d\u5bf9\uff0c\u63a5\u7740\u95ea\u73b0\u4e00\u4e2a\u5b57\u6bcd\u8981\u4f60\u8bb0\u4f4f\u3002\u505a\u5b8c\u4e00\u8fde\u4e32\u300c\u5148\u7b97\u672f\u3001\u518d\u5b57\u6bcd\u300d\u7684\u6b65\u9aa4\u540e\uff0c\u4f60\u8981\u6309\u5b57\u6bcd\u51fa\u73b0\u7684\u786e\u5207\u987a\u5e8f\u628a\u5b83\u4eec\u56de\u5fc6\u51fa\u6765\u3002\u8981\u70b9\u5728\u4e8e\uff1a\u4e00\u8fb9\u6709\u4e2a\u5e72\u6270\u4efb\u52a1\u4e0d\u505c\u5730\u60f3\u628a\u5b57\u6bcd\u4ece\u4f60\u8111\u4e2d\u6324\u51fa\u53bb\uff0c\u4f60\u4e00\u8fb9\u8fd8\u5f97\u7ee7\u7eed\u8bb0\u3002",benefit:"\u5b83\u7ed9\u5de5\u4f5c\u8bb0\u5fc6\u5bb9\u91cf\u52a0\u8d1f\u8377\uff0c\u5177\u4f53\u6765\u8bf4\uff0c\u662f\u5728\u7b2c\u4e8c\u4e2a\u4efb\u52a1\u4e89\u62a2\u6ce8\u610f\u529b\u7684\u540c\u65f6\uff0c\u4ecd\u80fd\u8bb0\u4f4f\u4e00\u4e32\u6761\u76ee\u7684\u80fd\u529b\u3002\u540c\u65f6\u8fdb\u884c\u5b58\u50a8\u4e0e\u52a0\u5de5\u7684\u8fd9\u79cd\u300c\u517c\u987e\u300d\uff0c\u8fde\u540c\u6297\u5e72\u6270\u80fd\u529b\uff0c\u6b63\u662f\u8fd9\u9879\u7ec3\u4e60\u6240\u65bd\u538b\u7684\u5730\u65b9\u3002",history:"\u5b83\u57281989\u5e74\u4f5c\u4e3a\u5b9e\u9a8c\u5ba4\u91cc\u8861\u91cf\u5de5\u4f5c\u8bb0\u5fc6\u7684\u6807\u5c3a\u51fa\u73b0\uff0c\u800c\u975e\u6e38\u620f\uff0c\u5e76\u6210\u4e3a\u8ba4\u77e5\u5fc3\u7406\u5b66\u4e2d\u88ab\u5f15\u7528\u6700\u591a\u7684\u590d\u6742\u5e7f\u5ea6\u4efb\u52a1\u4e4b\u4e00\u30022005\u5e74\uff0cUnsworth\u3001Heitz\u3001Schrock\u548cEngle\u53d1\u5e03\u4e86\u4e00\u4e2a\u81ea\u52a8\u5316\u3001\u7528\u9f20\u6807\u64cd\u4f5c\u3001\u80fd\u81ea\u52a8\u8ba1\u5206\u7684\u7248\u672c\uff0c\u4f7f\u5b83\u4ece\u6700\u521d\u7684\u5b9e\u9a8c\u5ba4\u6269\u6563\u5230\u6570\u767e\u9879\u7814\u7a76\uff0c\u540e\u6765\u53c8\u8fdb\u5165\u4e86\u8111\u8bad\u7ec3\u5e94\u7528\u3002",creator:"\u7531Marilyn Turner\u548cRandall\uff08Randy\uff09Engle\u4e8e1989\u5e74\u5728\u5357\u5361\u7f57\u6765\u7eb3\u5927\u5b66\u63d0\u51fa\uff0c\u4f5c\u4e3a\u5de5\u4f5c\u8bb0\u5fc6\u5bb9\u91cf\u7684\u6307\u6807\u3002\u5e7f\u4e3a\u4f7f\u7528\u7684\u81ea\u52a8\u5316\u7248\u672c\u7531Nash Unsworth\u3001Richard Heitz\u3001Josef Schrock\u548cRandall Engle\u4e8e2005\u5e74\u6784\u5efa\u3002",methods:"\u5148\u628a\u56de\u5fc6\u987a\u5e8f\u9501\u4f4f\u2014\u2014\u7528\u7a33\u5b9a\u7684\u8282\u594f\u9ed8\u9ed8\u590d\u8ff0\u90a3\u4e32\u4e0d\u65ad\u53d8\u957f\u7684\u5b57\u6bcd\uff0c\u7136\u540e\u518d\u6574\u4e2a\u5207\u6362\u5230\u6bcf\u9053\u7b97\u5f0f\u4e0a\uff0c\u505a\u5b8c\u518d\u5207\u56de\u6765\u3002\u522b\u8ba9\u7b97\u672f\u6210\u4e3a\u6f0f\u6389\u4e00\u4e2a\u5b57\u6bcd\u7684\u501f\u53e3\uff0c\u4e5f\u522b\u628a\u7b97\u672f\u653e\u6162\u5230\u5b9e\u9645\u4e0a\u53ea\u662f\u5728\u7a7a\u9699\u91cc\u80cc\u5b57\u6bcd\u3002\u53ea\u6709\u5f53\u4f60\u7684\u56de\u5fc6\u7a33\u5b9a\u53ef\u9760\u65f6\uff0c\u624d\u628a\u96c6\u5408\u957f\u5ea6\u5f80\u4e0a\u52a0\uff0c\u800c\u4e0d\u662f\u4ec5\u4ec5\u89c9\u5f97\u300c\u611f\u89c9\u7b80\u5355\u4e86\u300d\u5c31\u52a0\u3002",duration:"\u77ed\u800c\u4e13\u6ce8\u7684\u5c0f\u6bb5\u6548\u679c\u6700\u597d\uff1a\u6bcf\u6b21\u7ea610\u523015\u5206\u949f\uff0c\u4e00\u5468\u51e0\u6b21\u3002\u51c6\u786e\u7387\u5f00\u59cb\u4e0b\u6ed1\u65f6\u5c31\u505c\uff0c\u56e0\u4e3a\u53c8\u7d2f\u53c8\u9a6c\u864e\u7684\u7ec3\u4e60\uff0c\u7ec3\u51fa\u6765\u7684\u662f\u574f\u4e60\u60ef\u800c\u975e\u5bb9\u91cf\u3002",research:"\u8bc1\u636e\u6700\u6709\u529b\u7684\u6070\u6070\u662f\u4f60\u80fd\u60f3\u5230\u7684\u90a3\u90e8\u5206\uff1a\u4f60\u4f1a\u5728OSpan\u4ee5\u53ca\u4e0e\u4e4b\u9ad8\u5ea6\u76f8\u4f3c\u7684\u590d\u6742\u5e7f\u5ea6\u4efb\u52a1\u4e0a\u53d8\u5f97\u66f4\u597d\u3002\u4f5c\u4e3a\u6d4b\u91cf\u5de5\u5177\uff0c\u5b83\u80fd\u53ef\u9760\u5730\u9884\u6d4b\u6d41\u4f53\u667a\u529b\uff0c\u4f46\u90a3\u53ea\u662f\u76f8\u5173\uff0c\u5e76\u4e0d\u80fd\u8bc1\u660e\u53cd\u590d\u7ec3\u5b83\u5c31\u80fd\u63d0\u9ad8\u4f60\u7684\u667a\u529b\u3002\u5f53\u7814\u7a76\u8005\u771f\u53bb\u8bad\u7ec3\u4eba\u4eec\u505a\u590d\u6742\u5e7f\u5ea6\u4efb\u52a1\u65f6\uff0cHarrison\u7b49\u4eba\uff082013\uff09\u53d1\u73b0\u6536\u76ca\u8fc1\u79fb\u5230\u4e86\u5176\u4ed6\u5e7f\u5ea6\u4efb\u52a1\uff0c\u4f46\u672a\u8fc1\u79fb\u5230\u6d41\u4f53\u667a\u529b\uff1bRedick\u7b49\u4eba\uff082013\uff09\u5219\u538b\u6839\u6ca1\u53d1\u73b0\u4efb\u4f55\u5e7f\u6cdb\u8fc1\u79fb\uff0c\u6240\u4ee5\u5bf9\u300c\u63d0\u5347\u667a\u5546\u6216\u6574\u4f53\u8111\u529b\u300d\u4e4b\u7c7b\u7684\u8bf4\u6cd5\u8981\u4fdd\u6301\u8c28\u614e\u3002",rec:"\u628a\u7b97\u5f0f\u5f53\u6210\u4e00\u9053\u771f\u6b63\u7684\u5173\u5361\uff0c\u6bcf\u9053\u90fd\u8bda\u5b9e\u800c\u8fc5\u901f\u5730\u4f5c\u7b54\uff0c\u800c\u4e0d\u662f\u4e3a\u4e86\u62a4\u4f4f\u5b57\u6bcd\u5c31\u6577\u884d\u8499\u6df7\u8fc7\u53bb\u3002",faq:[["\u90a3\u4e9b\u7b97\u672f\u9898\u5e94\u8be5\u5f88\u96be\u5417\uff1f","\u4e0d\u3002\u7b97\u5f0f\u662f\u6545\u610f\u51fa\u5f97\u5f88\u7b80\u5355\u7684\u3002\u5b83\u4eec\u7684\u4f5c\u7528\u662f\u5360\u7528\u5e76\u5e72\u6270\u4f60\uff0c\u800c\u4e0d\u662f\u8003\u4f60\u7684\u6570\u5b66\uff0c\u6240\u4ee5\u6311\u6218\u5728\u4e8e\u4e00\u8fb9\u52a0\u5de5\u5b83\u4eec\u4e00\u8fb9\u8bb0\u4f4f\u5b57\u6bcd\u3002"],["\u7ec3\u8fd9\u4e2a\u4f1a\u8ba9\u6211\u6574\u4f53\u4e0a\u53d8\u806a\u660e\u5417\uff1f","\u8001\u5b9e\u8bf4\uff0c\u5728\u5e7f\u4e49\u4e0a\u5927\u6982\u4e0d\u4f1a\u3002\u4f60\u4f1a\u5728\u8fd9\u4e2a\u4efb\u52a1\u548c\u7c7b\u4f3c\u7684\u8bb0\u5fc6\u5e7f\u5ea6\u4efb\u52a1\u4e0a\u660e\u663e\u53d8\u597d\uff0c\u4f46\u5bf9\u7167\u7814\u7a76\u666e\u904d\u672a\u80fd\u663e\u793a\u51fa\u5411\u6d41\u4f53\u667a\u529b\u6216\u65e5\u5e38\u601d\u7ef4\u7684\u8fc1\u79fb\u3002"],["\u4e3a\u4ec0\u4e48\u6211\u5fc5\u987b\u6309\u987a\u5e8f\u56de\u5fc6\u5b57\u6bcd\uff1f","\u6b63\u662f\u300c\u6309\u987a\u5e8f\u56de\u5fc6\u300d\u8ba9\u5b83\u6210\u4e3a\u4e00\u9879\u771f\u6b63\u7684\u5de5\u4f5c\u8bb0\u5fc6\u6d4b\u9a8c\uff0c\u800c\u975e\u7b80\u5355\u7684\u518d\u8ba4\u3002\u5728\u5e72\u6270\u4e4b\u4e0b\u4fdd\u6301\u5e8f\u5217\u5b8c\u6574\uff0c\u6b63\u662f\u5b83\u6240\u8861\u91cf\u548c\u8bad\u7ec3\u7684\u5168\u90e8\u672c\u9886\u3002"]],variants:"\u8fd1\u4eb2\u7248\u672c\u628a\u7b97\u672f\u6362\u6210\u9700\u8981\u5224\u65ad\u662f\u5426\u8bf4\u5f97\u901a\u7684\u53e5\u5b50\uff08\u9605\u8bfb\u5e7f\u5ea6\uff09\uff0c\u6216\u6362\u6210\u7a7a\u95f4\u5bf9\u79f0\u6027\u5224\u65ad\uff08\u5bf9\u79f0\u5e7f\u5ea6\uff09\uff1b\u8981\u8bb0\u7684\u6761\u76ee\u53ef\u4ee5\u662f\u5b57\u6bcd\u3001\u6570\u5b57\u6216\u4f4d\u7f6e\u3002\u6709\u4e9b\u7248\u672c\u4f1a\u6839\u636e\u4f60\u7684\u8868\u73b0\u81ea\u9002\u5e94\u8c03\u6574\u96c6\u5408\u957f\u5ea6\uff0c\u800c\u6700\u521d\u7684\u5b9e\u9a8c\u5ba4\u4efb\u52a1\u7528\u7684\u662f\u5355\u8bcd\u800c\u975e\u5355\u4e2a\u5b57\u6bcd\u3002"}},pattern:{ru:{about:"\u0412 \u0442\u0440\u0435\u043d\u0430\u0436\u0451\u0440\u0435 \xab\u041f\u0430\u0442\u0442\u0435\u0440\u043d\u044b: \u0440\u0430\u0441\u0441\u0443\u0436\u0434\u0435\u043d\u0438\u0435\xbb \u043d\u0430 \u044d\u043a\u0440\u0430\u043d\u0435 \u0441\u0435\u0442\u043a\u0430 \u0438\u0437 \u0430\u0431\u0441\u0442\u0440\u0430\u043a\u0442\u043d\u044b\u0445 \u0444\u0438\u0433\u0443\u0440, \u0433\u0434\u0435 \u043e\u0434\u043d\u0430 \u044f\u0447\u0435\u0439\u043a\u0430 \u043f\u0443\u0441\u0442\u0430\u044f, \u0438 \u0440\u044f\u0434 \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u043e\u0432 \u043e\u0442\u0432\u0435\u0442\u0430. \u041d\u0443\u0436\u043d\u043e \u043f\u043e\u043d\u044f\u0442\u044c \u0441\u043a\u0440\u044b\u0442\u043e\u0435 \u043f\u0440\u0430\u0432\u0438\u043b\u043e, \u043f\u043e \u043a\u043e\u0442\u043e\u0440\u043e\u043c\u0443 \u0444\u0438\u0433\u0443\u0440\u044b \u043c\u0435\u043d\u044f\u044e\u0442\u0441\u044f \u043f\u043e \u0441\u0442\u0440\u043e\u043a\u0430\u043c \u0438 \u0441\u0442\u043e\u043b\u0431\u0446\u0430\u043c, \u0438 \u0432\u044b\u0431\u0440\u0430\u0442\u044c \u0435\u0434\u0438\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0439 \u0432\u0430\u0440\u0438\u0430\u043d\u0442, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u043f\u0440\u0430\u0432\u0438\u043b\u044c\u043d\u043e \u0434\u043e\u0441\u0442\u0440\u0430\u0438\u0432\u0430\u0435\u0442 \u0443\u0437\u043e\u0440.",benefit:"\u0422\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u043d\u0435\u0432\u0435\u0440\u0431\u0430\u043b\u044c\u043d\u043e\u0435 \u043b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u043e\u0435 \u043c\u044b\u0448\u043b\u0435\u043d\u0438\u0435: \u0443\u043c\u0435\u043d\u0438\u0435 \u0437\u0430\u043c\u0435\u0447\u0430\u0442\u044c \u0437\u0430\u043a\u043e\u043d\u043e\u043c\u0435\u0440\u043d\u043e\u0441\u0442\u0438, \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0442\u044c \u0432 \u0433\u043e\u043b\u043e\u0432\u0435 \u0441\u0440\u0430\u0437\u0443 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u043f\u0440\u0430\u0432\u0438\u043b \u0438 \u0432\u044b\u0432\u043e\u0434\u0438\u0442\u044c \u043b\u043e\u0433\u0438\u043a\u0443 \u043f\u043e\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u0438 \u0431\u0435\u0437 \u0441\u043b\u043e\u0432 \u0438 \u0437\u0430\u0440\u0430\u043d\u0435\u0435 \u0438\u0437\u0432\u0435\u0441\u0442\u043d\u044b\u0445 \u0444\u0430\u043a\u0442\u043e\u0432. \u041f\u043e\u043f\u0443\u0442\u043d\u043e \u0437\u0430\u0434\u0435\u0439\u0441\u0442\u0432\u0443\u0435\u0442 \u0440\u0430\u0431\u043e\u0447\u0443\u044e \u043f\u0430\u043c\u044f\u0442\u044c \u0438 \u043d\u0430\u0432\u044b\u043a \u0441\u0438\u0441\u0442\u0435\u043c\u043d\u043e\u0433\u043e \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u0433\u043e \u0430\u043d\u0430\u043b\u0438\u0437\u0430.",history:"\u0424\u043e\u0440\u043c\u0430\u0442 \u043c\u0430\u0442\u0440\u0438\u0446 \u0432\u043e\u0441\u0445\u043e\u0434\u0438\u0442 \u043a \u043f\u0440\u043e\u0433\u0440\u0435\u0441\u0441\u0438\u0432\u043d\u044b\u043c \u043c\u0430\u0442\u0440\u0438\u0446\u0430\u043c \u0420\u0430\u0432\u0435\u043d\u0430, \u0432\u043f\u0435\u0440\u0432\u044b\u0435 \u043e\u043f\u0438\u0441\u0430\u043d\u043d\u044b\u043c \u0432 \u0441\u0442\u0430\u0442\u044c\u0435 1936 \u0433\u043e\u0434\u0430 \u0438 \u0438\u0437\u0434\u0430\u043d\u043d\u044b\u043c \u043a\u0430\u043a \u0442\u0435\u0441\u0442 \u0432 1938-\u043c. \u041f\u043e\u0441\u043a\u043e\u043b\u044c\u043a\u0443 \u043e\u043d \u043d\u0435 \u0442\u0440\u0435\u0431\u0443\u0435\u0442 \u044f\u0437\u044b\u043a\u0430 \u0438 \u0431\u044b\u0441\u0442\u0440 \u0432 \u043f\u0440\u043e\u0432\u0435\u0434\u0435\u043d\u0438\u0438, \u043e\u043d \u0431\u044b\u0441\u0442\u0440\u043e \u0440\u0430\u0437\u043e\u0448\u0451\u043b\u0441\u044f: \u0441 1942 \u0433\u043e\u0434\u0430 \u043a\u043e\u0440\u043e\u0442\u043a\u0443\u044e \u0432\u0435\u0440\u0441\u0438\u044e \u043f\u0440\u043e\u0445\u043e\u0434\u0438\u043b \u043a\u0430\u0436\u0434\u044b\u0439 \u043d\u043e\u0432\u043e\u0431\u0440\u0430\u043d\u0435\u0446 \u0431\u0440\u0438\u0442\u0430\u043d\u0441\u043a\u043e\u0439 \u0430\u0440\u043c\u0438\u0438, \u0430 \u043f\u043e\u0437\u0436\u0435 \u043f\u043e\u0445\u043e\u0436\u0438\u0435 \u043c\u0430\u0442\u0440\u0438\u0447\u043d\u044b\u0435 \u0442\u0435\u0441\u0442\u044b \u043f\u0440\u0438\u043c\u0435\u043d\u044f\u043b\u0438\u0441\u044c \u0432 \u043f\u0440\u0438\u0437\u044b\u0432\u043d\u044b\u0445 \u0441\u0438\u0441\u0442\u0435\u043c\u0430\u0445 \u043f\u043e \u0432\u0441\u0435\u043c\u0443 \u043c\u0438\u0440\u0443, \u0432\u043a\u043b\u044e\u0447\u0430\u044f \u0421\u043e\u0432\u0435\u0442\u0441\u043a\u0438\u0439 \u0421\u043e\u044e\u0437. \u0421 \u0442\u0435\u0445 \u043f\u043e\u0440 \u0442\u0430\u043a\u0438\u0435 \u0437\u0430\u0434\u0430\u0447\u0438 \u0441\u0442\u0430\u043b\u0438 \u043f\u0440\u0438\u0432\u044b\u0447\u043d\u043e\u0439 \u0447\u0430\u0441\u0442\u044c\u044e \u0442\u0435\u0441\u0442\u043e\u0432 \u043d\u0430 IQ, \u0448\u043a\u043e\u043b\u044c\u043d\u044b\u0445 \u043f\u0440\u043e\u0432\u0435\u0440\u043e\u043a \u0438 \u043f\u0440\u0438\u043b\u043e\u0436\u0435\u043d\u0438\u0439 \u0434\u043b\u044f \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0438 \u043c\u043e\u0437\u0433\u0430.",creator:"\u041f\u0440\u044f\u043c\u043e\u0439 \u043f\u0440\u0435\u0434\u043e\u043a \u044d\u0442\u043e\u0433\u043e \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u044f \u2014 \u043f\u0440\u043e\u0433\u0440\u0435\u0441\u0441\u0438\u0432\u043d\u044b\u0435 \u043c\u0430\u0442\u0440\u0438\u0446\u044b \u0420\u0430\u0432\u0435\u043d\u0430, \u043f\u0440\u0438\u0434\u0443\u043c\u0430\u043d\u043d\u044b\u0435 \u0431\u0440\u0438\u0442\u0430\u043d\u0441\u043a\u0438\u043c \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u043e\u043c \u0414\u0436\u043e\u043d\u043e\u043c \u0420\u0430\u0432\u0435\u043d\u043e\u043c \u0432\u043c\u0435\u0441\u0442\u0435 \u0441 \u0433\u0435\u043d\u0435\u0442\u0438\u043a\u043e\u043c \u041b\u0430\u0439\u043e\u043d\u0435\u043b\u043e\u043c \u041f\u0435\u043d\u0440\u043e\u0443\u0437\u043e\u043c \u0432 1936 \u0433\u043e\u0434\u0443. \u0421\u0430\u043c\u0430 \u0437\u0430\u0434\u0430\u0447\u0430 \u043d\u0430 \u0434\u043e\u0441\u0442\u0440\u0430\u0438\u0432\u0430\u043d\u0438\u0435 \u043c\u0430\u0442\u0440\u0438\u0446\u044b \u0434\u0430\u0432\u043d\u043e \u0441\u0442\u0430\u043b\u0430 \u0443\u043d\u0438\u0432\u0435\u0440\u0441\u0430\u043b\u044c\u043d\u044b\u043c \u0444\u043e\u0440\u043c\u0430\u0442\u043e\u043c \u0441 \u043c\u043d\u043e\u0436\u0435\u0441\u0442\u0432\u043e\u043c \u0440\u0430\u0437\u043d\u043e\u0432\u0438\u0434\u043d\u043e\u0441\u0442\u0435\u0439, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u0443 \u0442\u043e\u0433\u043e \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u0430, \u0447\u0442\u043e \u0432\u044b \u0432\u0438\u0434\u0438\u0442\u0435 \u0437\u0434\u0435\u0441\u044c, \u043d\u0435\u0442 \u0435\u0434\u0438\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0433\u043e \u0430\u0432\u0442\u043e\u0440\u0430, \u043d\u043e \u0440\u043e\u0434\u043e\u0441\u043b\u043e\u0432\u043d\u0430\u044f \u0432\u0435\u0434\u0451\u0442 \u043f\u0440\u044f\u043c\u043e \u043a \u0440\u0430\u0431\u043e\u0442\u0435 \u0420\u0430\u0432\u0435\u043d\u0430.",methods:"\u0420\u0430\u0437\u0431\u0438\u0440\u0430\u0439\u0442\u0435 \u043c\u0430\u0442\u0440\u0438\u0446\u0443 \u043f\u043e \u043e\u0434\u043d\u043e\u043c\u0443 \u0438\u0437\u043c\u0435\u0440\u0435\u043d\u0438\u044e \u0437\u0430 \u0440\u0430\u0437: \u0441\u043d\u0430\u0447\u0430\u043b\u0430 \u0441\u043f\u0440\u043e\u0441\u0438\u0442\u0435, \u0447\u0442\u043e \u043c\u0435\u043d\u044f\u0435\u0442\u0441\u044f \u0441\u043b\u0435\u0432\u0430 \u043d\u0430\u043f\u0440\u0430\u0432\u043e \u0432 \u0441\u0442\u0440\u043e\u043a\u0435, \u0437\u0430\u0442\u0435\u043c \u0447\u0442\u043e \u043c\u0435\u043d\u044f\u0435\u0442\u0441\u044f \u0441\u0432\u0435\u0440\u0445\u0443 \u0432\u043d\u0438\u0437 \u0432 \u0441\u0442\u043e\u043b\u0431\u0446\u0435, \u0438 \u0442\u043e\u043b\u044c\u043a\u043e \u043f\u043e\u0442\u043e\u043c \u0441\u043e\u0435\u0434\u0438\u043d\u044f\u0439\u0442\u0435 \u043e\u0431\u0430 \u043f\u0440\u0430\u0432\u0438\u043b\u0430. \u041e\u0442\u0441\u043b\u0435\u0436\u0438\u0432\u0430\u0439\u0442\u0435 \u043a\u0430\u0436\u0434\u044b\u0439 \u043f\u0440\u0438\u0437\u043d\u0430\u043a \u043e\u0442\u0434\u0435\u043b\u044c\u043d\u043e \u2014 \u0444\u043e\u0440\u043c\u0443, \u043a\u043e\u043b\u0438\u0447\u0435\u0441\u0442\u0432\u043e, \u0440\u0430\u0437\u043c\u0435\u0440, \u043f\u043e\u0432\u043e\u0440\u043e\u0442, \u0437\u0430\u043b\u0438\u0432\u043a\u0443, \u043f\u043e\u043b\u043e\u0436\u0435\u043d\u0438\u0435. \u041d\u0435 \u0438\u0449\u0438\u0442\u0435 \xab\u043f\u043e\u0445\u043e\u0436\u0438\u0439\xbb \u043e\u0442\u0432\u0435\u0442, \u0430 \u043e\u0442\u0431\u0440\u0430\u0441\u044b\u0432\u0430\u0439\u0442\u0435 \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u044b, \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u043d\u0430\u0440\u0443\u0448\u0430\u044e\u0442 \u0445\u043e\u0442\u044c \u043e\u0434\u043d\u043e \u043f\u0440\u0430\u0432\u0438\u043b\u043e, \u0438 \u043d\u0430 \u0441\u043b\u043e\u0436\u043d\u044b\u0445 \u0437\u0430\u0434\u0430\u043d\u0438\u044f\u0445 \u043f\u0440\u043e\u0432\u0435\u0440\u044f\u0439\u0442\u0435 \u0441\u0432\u043e\u0439 \u0432\u044b\u0431\u043e\u0440 \u0438 \u043f\u043e \u0441\u0442\u0440\u043e\u043a\u0435, \u0438 \u043f\u043e \u0441\u0442\u043e\u043b\u0431\u0446\u0443.",duration:"\u041b\u0443\u0447\u0448\u0435 \u0440\u0430\u0431\u043e\u0442\u0430\u044e\u0442 \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u0435 \u0441\u043e\u0441\u0440\u0435\u0434\u043e\u0442\u043e\u0447\u0435\u043d\u043d\u044b\u0435 \u043f\u043e\u0434\u0445\u043e\u0434\u044b: 10\u201315 \u043c\u0438\u043d\u0443\u0442 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0440\u0430\u0437 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e. \u041e\u0441\u0442\u0430\u043d\u0430\u0432\u043b\u0438\u0432\u0430\u0439\u0442\u0435\u0441\u044c, \u043a\u0430\u043a \u0442\u043e\u043b\u044c\u043a\u043e \u043d\u0430\u0447\u0438\u043d\u0430\u0435\u0442\u0435 \u0433\u0430\u0434\u0430\u0442\u044c, \u2014 \u043d\u0430 \u0443\u0441\u0442\u0430\u043b\u043e\u0441\u0442\u0438 \u0440\u0430\u0441\u0441\u0443\u0436\u0434\u0435\u043d\u0438\u0435 \u043f\u0440\u0435\u0432\u0440\u0430\u0449\u0430\u0435\u0442\u0441\u044f \u0432 \u0443\u0433\u0430\u0434\u044b\u0432\u0430\u043d\u0438\u0435 \u0443\u0437\u043e\u0440\u0430, \u0438 \u043e\u0431\u0443\u0447\u0435\u043d\u0438\u0435 \u043f\u0440\u0435\u043a\u0440\u0430\u0449\u0430\u0435\u0442\u0441\u044f.",research:"\u041d\u0430\u0434\u0451\u0436\u043d\u043e \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043d\u043e \u043e\u0436\u0438\u0434\u0430\u0435\u043c\u043e\u0435: \u0441 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u043e\u0439 \u0432\u044b \u043b\u0443\u0447\u0448\u0435 \u0440\u0435\u0448\u0430\u0435\u0442\u0435 \u0441\u0430\u043c\u0438 \u043c\u0430\u0442\u0440\u0438\u0446\u044b, \u0430 \u043f\u043e\u0432\u0442\u043e\u0440\u043d\u043e\u0435 \u043f\u0440\u043e\u0445\u043e\u0436\u0434\u0435\u043d\u0438\u0435 \u0441\u0442\u0430\u0431\u0438\u043b\u044c\u043d\u043e \u043f\u043e\u0432\u044b\u0448\u0430\u0435\u0442 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442 \u043d\u0430 \u0442\u0430\u043a\u0438\u0445 \u0437\u0430\u0434\u0430\u043d\u0438\u044f\u0445 \u0434\u0430\u0436\u0435 \u0431\u0435\u0437 \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u043e\u043a \u0438 \u043e\u0431\u0443\u0447\u0435\u043d\u0438\u044f. \u041e\u0442\u0440\u0430\u0436\u0430\u0435\u0442 \u043b\u0438 \u044d\u0442\u043e\u0442 \u043f\u0440\u0438\u0440\u043e\u0441\u0442 \u0431\u043e\u043b\u0435\u0435 \u043e\u0441\u0442\u0440\u043e\u0435 \u043c\u044b\u0448\u043b\u0435\u043d\u0438\u0435 \u0432 \u0446\u0435\u043b\u043e\u043c \u0438\u043b\u0438 \u043f\u0440\u043e\u0441\u0442\u043e \u043d\u0430\u0432\u044b\u043a \u043f\u0440\u043e\u0445\u043e\u0434\u0438\u0442\u044c \u0442\u0435\u0441\u0442\u044b \u2014 \u0432\u043e\u043f\u0440\u043e\u0441 \u0441\u043f\u043e\u0440\u043d\u044b\u0439, \u0430 \u0441\u0430\u043c\u043e\u0435 \u0433\u0440\u043e\u043c\u043a\u043e\u0435 \u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043d\u0438\u0435, \u0447\u0442\u043e \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0430 \u0430\u0431\u0441\u0442\u0440\u0430\u043a\u0442\u043d\u043e\u0433\u043e \u043c\u044b\u0448\u043b\u0435\u043d\u0438\u044f \u0448\u0438\u0440\u043e\u043a\u043e \u043f\u043e\u0432\u044b\u0448\u0430\u0435\u0442 \u043f\u043e\u0434\u0432\u0438\u0436\u043d\u044b\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0438\u043b\u0438 IQ, \u0434\u043e\u043a\u0430\u0437\u0430\u043d\u043e \u0441\u043b\u0430\u0431\u043e. \u0418\u0437\u0432\u0435\u0441\u0442\u043d\u044b\u0439 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442 \u043e \u0442\u043e\u043c, \u0447\u0442\u043e \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0430 dual n-back \u0443\u043b\u0443\u0447\u0448\u0430\u0435\u0442 \u0440\u0435\u0448\u0435\u043d\u0438\u0435 \u043c\u0430\u0442\u0440\u0438\u0446, \u0432 \u043e\u0441\u043d\u043e\u0432\u043d\u043e\u043c \u043d\u0435 \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u0451\u043b\u0441\u044f \u043f\u0440\u0438 \u043f\u043e\u0432\u0442\u043e\u0440\u043d\u044b\u0445 \u043f\u0440\u043e\u0432\u0435\u0440\u043a\u0430\u0445, \u0442\u0430\u043a \u0447\u0442\u043e \u043a \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f\u043c \xab\u043f\u0440\u043e\u043a\u0430\u0447\u0430\u0442\u044c \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0432\u043e\u043e\u0431\u0449\u0435\xbb \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u0435\u0441\u044c \u043e\u0441\u0442\u043e\u0440\u043e\u0436\u043d\u043e.",rec:"\u041d\u0430 \u0442\u0440\u0443\u0434\u043d\u044b\u0445 \u0437\u0430\u0434\u0430\u043d\u0438\u044f\u0445 \u043d\u0435 \u0442\u043e\u0440\u043e\u043f\u0438\u0442\u0435\u0441\u044c \u0438 \u043f\u0440\u043e\u0433\u043e\u0432\u0430\u0440\u0438\u0432\u0430\u0439\u0442\u0435 \u043f\u0440\u0430\u0432\u0438\u043b\u043e \u0432\u0441\u043b\u0443\u0445, \u043f\u0440\u0435\u0436\u0434\u0435 \u0447\u0435\u043c \u043d\u0430\u0436\u0430\u0442\u044c: \u0441\u043b\u043e\u0432\u0435\u0441\u043d\u0430\u044f \u0444\u043e\u0440\u043c\u0443\u043b\u0438\u0440\u043e\u0432\u043a\u0430 \u043b\u043e\u0433\u0438\u043a\u0438 \u043b\u043e\u0432\u0438\u0442 \u043e\u0448\u0438\u0431\u043a\u0438, \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u043f\u0440\u043e\u0441\u043a\u0430\u043a\u0438\u0432\u0430\u044e\u0442 \u043f\u0440\u0438 \u0431\u044b\u0441\u0442\u0440\u043e\u043c \u0443\u0437\u043d\u0430\u0432\u0430\u043d\u0438\u0438.",faq:[["\u041f\u043e\u0434\u043d\u0438\u043c\u0435\u0442 \u043b\u0438 \u044d\u0442\u043e \u043c\u043e\u0439 IQ?","\u0427\u0435\u0441\u0442\u043d\u043e \u2014 \u0441\u043a\u043e\u0440\u0435\u0435 \u0432\u0441\u0435\u0433\u043e \u043d\u0435\u0442, \u0435\u0441\u043b\u0438 \u0433\u043e\u0432\u043e\u0440\u0438\u0442\u044c \u043f\u0440\u043e \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0432\u043e\u043e\u0431\u0449\u0435. \u0412\u044b \u0437\u0430\u043c\u0435\u0442\u043d\u043e \u043b\u0443\u0447\u0448\u0435 \u0441\u0442\u0430\u043d\u0435\u0442\u0435 \u0440\u0435\u0448\u0430\u0442\u044c \u043c\u0430\u0442\u0440\u0438\u0446\u044b \u0438 \u043f\u043e\u0445\u043e\u0436\u0438\u0435 \u043b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u0438\u0435 \u0437\u0430\u0434\u0430\u0447\u0438, \u043d\u043e \u0434\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432, \u0447\u0442\u043e \u043d\u0430\u0432\u044b\u043a \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0438\u0442\u0441\u044f \u043d\u0430 \u0448\u0438\u0440\u043e\u043a\u0438\u0439, \u0436\u0438\u0437\u043d\u0435\u043d\u043d\u044b\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442, \u043c\u0430\u043b\u043e, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u0440\u043e\u0441\u0442\u0430 IQ \u043c\u044b \u043d\u0435 \u043e\u0431\u0435\u0449\u0430\u0435\u043c."],["\u0427\u0435\u043c \u044d\u0442\u043e \u043e\u0442\u043b\u0438\u0447\u0430\u0435\u0442\u0441\u044f \u043e\u0442 \u0438\u0433\u0440\u044b \u043d\u0430 \u043f\u0430\u043c\u044f\u0442\u044c?","\u0418\u0433\u0440\u044b \u043d\u0430 \u043f\u0430\u043c\u044f\u0442\u044c \u043f\u0440\u043e\u0432\u0435\u0440\u044f\u044e\u0442, \u0447\u0442\u043e \u0432\u044b \u0441\u043f\u043e\u0441\u043e\u0431\u043d\u044b \u0443\u0434\u0435\u0440\u0436\u0430\u0442\u044c \u0438 \u0432\u0441\u043f\u043e\u043c\u043d\u0438\u0442\u044c; \u0437\u0434\u0435\u0441\u044c \u043f\u0440\u043e\u0432\u0435\u0440\u044f\u0435\u0442\u0441\u044f, \u0447\u0442\u043e \u0432\u044b \u0441\u043f\u043e\u0441\u043e\u0431\u043d\u044b \u0432\u044b\u0432\u0435\u0441\u0442\u0438. \u0417\u0430\u043f\u043e\u043c\u0438\u043d\u0430\u0442\u044c \u043d\u0438\u0447\u0435\u0433\u043e \u043d\u0435 \u043d\u0443\u0436\u043d\u043e \u2014 \u0432\u0441\u044f \u0437\u0430\u0434\u0430\u0447\u0430 \u043e\u0441\u0442\u0430\u0451\u0442\u0441\u044f \u043d\u0430 \u044d\u043a\u0440\u0430\u043d\u0435, \u0430 \u0441\u043b\u043e\u0436\u043d\u043e\u0441\u0442\u044c \u0432 \u0442\u043e\u043c, \u0447\u0442\u043e\u0431\u044b \u0432\u044b\u0447\u0438\u0441\u043b\u0438\u0442\u044c \u043f\u0440\u0430\u0432\u0438\u043b\u043e, \u0441\u0432\u044f\u0437\u044b\u0432\u0430\u044e\u0449\u0435\u0435 \u0444\u0438\u0433\u0443\u0440\u044b."],["\u041f\u043e\u0441\u0442\u043e\u044f\u043d\u043d\u043e \u043e\u0448\u0438\u0431\u0430\u044e\u0441\u044c \u043d\u0430 \u0441\u043b\u043e\u0436\u043d\u044b\u0445. \u0427\u0442\u043e \u044f \u0443\u043f\u0443\u0441\u043a\u0430\u044e?","\u041e\u0431\u044b\u0447\u043d\u043e \u043e\u0434\u043d\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u043e \u0440\u0430\u0431\u043e\u0442\u0430\u0435\u0442 \u043d\u0435 \u043e\u0434\u043d\u043e \u043f\u0440\u0430\u0432\u0438\u043b\u043e, \u0430 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e. \u0420\u0435\u0448\u0430\u0439\u0442\u0435 \u043a\u0430\u0436\u0434\u044b\u0439 \u043f\u0440\u0438\u0437\u043d\u0430\u043a \u043f\u043e \u043e\u0442\u0434\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u0438 \u2014 \u0441\u043d\u0430\u0447\u0430\u043b\u0430 \u0444\u043e\u0440\u043c\u0443, \u043f\u043e\u0442\u043e\u043c \u043a\u043e\u043b\u0438\u0447\u0435\u0441\u0442\u0432\u043e, \u043f\u043e\u0442\u043e\u043c \u043f\u043e\u0432\u043e\u0440\u043e\u0442, \u043f\u043e\u0442\u043e\u043c \u0437\u0430\u043b\u0438\u0432\u043a\u0443 \u2014 \u0438 \u0441\u0432\u0435\u0440\u044f\u0439\u0442\u0435 \u0441\u0432\u043e\u0439 \u0432\u044b\u0431\u043e\u0440 \u0438 \u043f\u043e \u0441\u0442\u0440\u043e\u043a\u0435, \u0438 \u043f\u043e \u0441\u0442\u043e\u043b\u0431\u0446\u0443, \u043f\u0440\u0435\u0436\u0434\u0435 \u0447\u0435\u043c \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0434\u0438\u0442\u044c."]],variants:"\u0412\u0430\u0440\u0438\u0430\u043d\u0442\u044b \u0438\u0434\u0443\u0442 \u043e\u0442 \u043f\u0440\u043e\u0441\u0442\u044b\u0445 \u0441\u0435\u0442\u043e\u043a 2x2 \u0434\u043e \u043f\u043b\u043e\u0442\u043d\u044b\u0445 \u043c\u0430\u0442\u0440\u0438\u0446 3x3 \u0441 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u0438\u043c\u0438 \u043d\u0430\u043b\u043e\u0436\u0435\u043d\u043d\u044b\u043c\u0438 \u043f\u0440\u0430\u0432\u0438\u043b\u0430\u043c\u0438; \u0433\u0434\u0435-\u0442\u043e \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0435\u0442\u0441\u044f \u0446\u0432\u0435\u0442, \u0433\u0434\u0435-\u0442\u043e \u0442\u043e\u043b\u044c\u043a\u043e \u0447\u0451\u0440\u043d\u043e-\u0431\u0435\u043b\u044b\u0435 \u0444\u0438\u0433\u0443\u0440\u044b. \u0411\u043b\u0438\u0437\u043a\u0438\u0435 \u0440\u043e\u0434\u0441\u0442\u0432\u0435\u043d\u043d\u0438\u043a\u0438 \u2014 \u0447\u0438\u0441\u043b\u043e\u0432\u044b\u0435 \u0438 \u0431\u0443\u043a\u0432\u0435\u043d\u043d\u044b\u0435 \u0440\u044f\u0434\u044b, \u0437\u0430\u0434\u0430\u0447\u0438 \xab\u043d\u0430\u0439\u0434\u0438 \u043b\u0438\u0448\u043d\u0435\u0435\xbb, \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0435 \u0430\u043d\u0430\u043b\u043e\u0433\u0438\u0438 (A \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u0441\u044f \u043a B, \u043a\u0430\u043a C \u043a ?) \u0438 \u0437\u0430\u0434\u0430\u043d\u0438\u044f \u043d\u0430 \u043c\u044b\u0441\u043b\u0435\u043d\u043d\u0443\u044e \u0440\u0430\u0437\u0432\u0451\u0440\u0442\u043a\u0443 \u0444\u0438\u0433\u0443\u0440, \u0438 \u0432\u0441\u0435 \u043e\u043d\u0438 \u043f\u043e\u0441\u0442\u0440\u043e\u0435\u043d\u044b \u043d\u0430 \u0442\u043e\u0439 \u0436\u0435 \u0438\u0434\u0435\u0435 \xab\u043d\u0430\u0439\u0434\u0438 \u043f\u0440\u0430\u0432\u0438\u043b\u043e\xbb."},en:{about:"Patterns: Reasoning shows you a grid of abstract figures with one cell left blank, plus a row of candidate answers. Your job is to work out the hidden rule that governs how the figures change across the rows and columns, then pick the single option that completes the pattern.",benefit:"It exercises non-verbal, fluid reasoning: spotting relationships, holding several rules in mind at once, and inferring the logic behind a sequence without any words or prior knowledge. It also leans on working memory and systematic visual analysis.",history:"The matrix format goes back to the Raven's Progressive Matrices, first described in a 1936 paper and published as a test in 1938. Because it needs no language and is quick to administer, it spread fast: from 1942 every recruit to the British armed forces took a short version, and similar matrix tests later ran in conscript services worldwide, including the Soviet Union. The puzzle style has since become a staple of IQ tests, school assessments and brain-training apps.",creator:"The standard ancestor is Raven's Progressive Matrices, devised by British psychologist John C. Raven together with geneticist Lionel Penrose in 1936. The matrix-completion puzzle itself is now a generic format with countless variants, so no single person owns the kind you see here, but the lineage traces straight back to Raven's original work.",methods:"Read the matrix one dimension at a time: first ask what changes from left to right across a row, then what changes top to bottom down a column, and only then combine the two. Track each attribute separately such as shape, count, size, rotation, shading and position. Eliminate options that break any rule rather than hunting for the one that looks right, and on hard items check your answer against both the row rule and the column rule.",duration:"Short, focused sets work best: 10 to 15 minutes, a few times a week. Stop when items start feeling like guesswork, since fatigue turns reasoning into pattern-guessing and you stop learning.",research:"The solid finding is the unsurprising one: with practice you get better at matrix puzzles themselves, and repeated testing reliably raises your score on this kind of task even without coaching. Whether that gain reflects sharper general reasoning or just better test-taking strategy is debated, and the strongest claim, that training abstract reasoning broadly raises fluid intelligence or IQ, is weak. The famous result that dual n-back training boosts matrix reasoning largely failed to replicate, so treat any promise of a general intelligence boost with caution.",rec:"Slow down on the hard items and name the rule out loud before you tap; verbalising the logic catches mistakes that fast pattern-matching misses.",faq:[["Will this raise my IQ?","Honestly, probably not in any general sense. You will get noticeably better at matrix puzzles and similar reasoning tasks, but evidence that the skill spreads to broad, real-world intelligence is weak, so we do not promise an IQ boost."],["How is this different from a memory game?","Memory games test what you can hold and recall; this tests what you can infer. Nothing needs to be memorised, the whole puzzle stays on screen and the challenge is reasoning out the rule that connects the figures."],["I keep getting the hard ones wrong. What am I missing?","Usually there is more than one rule running at once. Solve each attribute separately such as shape, then count, then rotation, then shading, and verify your pick against both the row and the column before committing."]],variants:"Versions range from simple 2x2 grids up to dense 3x3 matrices with several overlapping rules; some use colour, some only black-and-white. Close relatives include number and letter series, odd-one-out sets, visual analogies (A is to B as C is to ?) and figure-folding tasks, all built on the same find-the-rule idea."},es:{about:"Patrones: Razonamiento te muestra una cuadr\xedcula de figuras abstractas con una celda en blanco, junto a una fila de respuestas candidatas. Tu tarea es deducir la regla oculta que rige c\xf3mo cambian las figuras a lo largo de las filas y las columnas, y luego elegir la \xfanica opci\xf3n que completa el patr\xf3n.",benefit:"Ejercita el razonamiento fluido no verbal: detectar relaciones, mantener varias reglas en mente a la vez e inferir la l\xf3gica detr\xe1s de una secuencia sin palabras ni conocimientos previos. Tambi\xe9n se apoya en la memoria de trabajo y en el an\xe1lisis visual sistem\xe1tico.",history:"El formato de matriz se remonta a las Matrices Progresivas de Raven, descritas por primera vez en un art\xedculo de 1936 y publicadas como test en 1938. Como no requiere lenguaje y se administra con rapidez, se difundi\xf3 r\xe1pido: desde 1942 todo recluta de las fuerzas armadas brit\xe1nicas hac\xeda una versi\xf3n breve, y m\xe1s tarde se aplicaron tests de matrices similares en servicios de conscripci\xf3n de todo el mundo, incluida la Uni\xf3n Sovi\xe9tica. Desde entonces este estilo de puzle se ha vuelto un pilar de los tests de inteligencia, las evaluaciones escolares y las apps de entrenamiento mental.",creator:"El antecesor est\xe1ndar son las Matrices Progresivas de Raven, ideadas por el psic\xf3logo brit\xe1nico John C. Raven junto con el genetista Lionel Penrose en 1936. El puzle de completar matrices en s\xed es hoy un formato gen\xe9rico con innumerables variantes, as\xed que nadie en particular es due\xf1o del tipo que ves aqu\xed, pero el linaje se remonta directamente al trabajo original de Raven.",methods:"Lee la matriz de una dimensi\xf3n a la vez: primero preg\xfantate qu\xe9 cambia de izquierda a derecha a lo largo de una fila, luego qu\xe9 cambia de arriba abajo por una columna, y solo entonces combina ambas. Sigue cada atributo por separado, como forma, cantidad, tama\xf1o, rotaci\xf3n, sombreado y posici\xf3n. Elimina las opciones que rompen cualquier regla en lugar de cazar la que parece correcta, y en los \xedtems dif\xedciles comprueba tu respuesta contra la regla de la fila y la de la columna.",duration:"Los conjuntos cortos y concentrados funcionan mejor: de 10 a 15 minutos, unas cuantas veces por semana. Detente cuando los \xedtems empiecen a sentirse como adivinanza, porque el cansancio convierte el razonamiento en mero acierto al azar y dejas de aprender.",research:"El hallazgo s\xf3lido es el poco sorprendente: con la pr\xe1ctica mejoras en los puzles de matrices en s\xed, y la repetici\xf3n de pruebas eleva de forma fiable tu puntuaci\xf3n en este tipo de tarea incluso sin entrenamiento guiado. Si esa mejora refleja un razonamiento general m\xe1s afilado o solo una mejor estrategia para hacer tests es objeto de debate, y la afirmaci\xf3n m\xe1s fuerte \u2014que entrenar el razonamiento abstracto eleve de forma amplia la inteligencia fluida o el CI\u2014 es d\xe9bil. El famoso resultado de que el entrenamiento dual n-back mejora el razonamiento con matrices en gran medida no logr\xf3 replicarse, as\xed que toma con cautela cualquier promesa de un aumento de la inteligencia general.",rec:"Baja el ritmo en los \xedtems dif\xedciles y nombra la regla en voz alta antes de tocar; verbalizar la l\xf3gica detecta errores que el reconocimiento r\xe1pido de patrones pasa por alto.",faq:[["\xbfEsto elevar\xe1 mi CI?","Sinceramente, probablemente no en ning\xfan sentido general. Mejorar\xe1s de forma notable en los puzles de matrices y en tareas de razonamiento similares, pero la evidencia de que la habilidad se extienda a una inteligencia amplia y del mundo real es d\xe9bil, as\xed que no prometemos un aumento del CI."],["\xbfEn qu\xe9 se diferencia de un juego de memoria?","Los juegos de memoria ponen a prueba lo que puedes retener y recordar; este pone a prueba lo que puedes inferir. No hay que memorizar nada, todo el puzle permanece en pantalla y el reto es razonar la regla que conecta las figuras."],["Sigo fallando los dif\xedciles. \xbfQu\xe9 se me escapa?","Por lo general hay m\xe1s de una regla operando a la vez. Resuelve cada atributo por separado, como la forma, luego la cantidad, luego la rotaci\xf3n, luego el sombreado, y verifica tu elecci\xf3n contra la fila y la columna antes de confirmar."]],variants:"Las versiones van desde simples cuadr\xedculas de 2x2 hasta densas matrices de 3x3 con varias reglas superpuestas; algunas usan color, otras solo blanco y negro. Entre sus parientes cercanos est\xe1n las series de n\xfameros y letras, los conjuntos de \"encuentra el intruso\", las analog\xedas visuales (A es a B como C es a ?) y las tareas de plegado de figuras, todas construidas sobre la misma idea de hallar la regla."},de:{about:"Patterns: Reasoning zeigt dir ein Raster abstrakter Figuren mit einer leeren Zelle sowie eine Reihe m\xf6glicher Antworten. Deine Aufgabe ist es, die verborgene Regel herauszufinden, nach der sich die Figuren \xfcber die Zeilen und Spalten hinweg ver\xe4ndern, und dann die eine Option zu w\xe4hlen, die das Muster vervollst\xe4ndigt.",benefit:"Es trainiert das nonverbale, fluide Schlussfolgern: Beziehungen zu erkennen, mehrere Regeln gleichzeitig im Kopf zu behalten und die Logik hinter einer Abfolge ohne Worte oder Vorwissen abzuleiten. Es st\xfctzt sich au\xdferdem auf das Arbeitsged\xe4chtnis und systematische visuelle Analyse.",history:"Das Matrix-Format geht auf die Raven-Matrizen (Raven's Progressive Matrices) zur\xfcck, die erstmals 1936 in einem Aufsatz beschrieben und 1938 als Test ver\xf6ffentlicht wurden. Weil er keine Sprache braucht und schnell durchf\xfchrbar ist, verbreitete er sich rasch: Ab 1942 absolvierte jeder Rekrut der britischen Streitkr\xe4fte eine Kurzfassung, und \xe4hnliche Matrizentests liefen sp\xe4ter weltweit im Wehrdienst, auch in der Sowjetunion. Der R\xe4tseltyp ist seitdem ein fester Bestandteil von IQ-Tests, Schultests und Gehirntraining-Apps geworden.",creator:"Der Standard-Vorl\xe4ufer sind Raven's Progressive Matrices, ersonnen vom britischen Psychologen John C. Raven zusammen mit dem Genetiker Lionel Penrose im Jahr 1936. Das Matrizen-Erg\xe4nzungsr\xe4tsel selbst ist heute ein allgemeines Format mit unz\xe4hligen Varianten, sodass niemand allein die Art besitzt, die du hier siehst, aber die Linie f\xfchrt direkt auf Ravens Originalarbeit zur\xfcck.",methods:"Lies die Matrix Dimension f\xfcr Dimension: Frage zuerst, was sich von links nach rechts entlang einer Zeile \xe4ndert, dann was sich von oben nach unten entlang einer Spalte \xe4ndert, und kombiniere beides erst danach. Verfolge jedes Merkmal getrennt, etwa Form, Anzahl, Gr\xf6\xdfe, Drehung, Schattierung und Position. Schlie\xdfe Optionen aus, die irgendeine Regel brechen, statt nach der zu jagen, die richtig aussieht, und pr\xfcfe deine Antwort bei schweren Aufgaben sowohl gegen die Zeilenregel als auch die Spaltenregel.",duration:"Kurze, konzentrierte S\xe4tze funktionieren am besten: 10 bis 15 Minuten, ein paar Mal pro Woche. H\xf6r auf, wenn die Aufgaben sich wie Raterei anf\xfchlen, denn M\xfcdigkeit verwandelt Schlussfolgern in Musterraten, und du lernst nichts mehr.",research:"Der solide Befund ist der wenig \xfcberraschende: Mit \xdcbung wirst du besser bei Matrizenr\xe4tseln selbst, und wiederholtes Testen hebt deinen Wert bei dieser Art Aufgabe zuverl\xe4ssig, auch ohne Anleitung. Ob dieser Zuwachs sch\xe4rferes allgemeines Schlussfolgern widerspiegelt oder nur eine bessere Testbearbeitungsstrategie, ist umstritten, und die st\xe4rkste Behauptung, dass das Trainieren abstrakten Denkens die fluide Intelligenz oder den IQ breit anhebt, ist schwach belegt. Das ber\xfchmte Ergebnis, dass Dual-n-Back-Training das Matrizen-Schlussfolgern steigert, lie\xdf sich weitgehend nicht replizieren, also begegne jedem Versprechen einer allgemeinen Intelligenzsteigerung mit Vorsicht.",rec:"Werde bei den schweren Aufgaben langsamer und benenne die Regel laut, bevor du tippst; das Versprachlichen der Logik f\xe4ngt Fehler ab, die schnelles Mustererkennen \xfcbersieht.",faq:[["Hebt das meinen IQ?","Ehrlich gesagt, in keinem allgemeinen Sinn. Du wirst sp\xfcrbar besser bei Matrizenr\xe4tseln und \xe4hnlichen Denkaufgaben, aber der Beleg daf\xfcr, dass sich die F\xe4higkeit auf breite, reale Intelligenz \xfcbertr\xe4gt, ist schwach, also versprechen wir keine IQ-Steigerung."],["Wie unterscheidet sich das von einem Ged\xe4chtnisspiel?","Ged\xe4chtnisspiele pr\xfcfen, was du behalten und abrufen kannst; dies pr\xfcft, was du erschlie\xdfen kannst. Nichts muss auswendig gelernt werden, das gesamte R\xe4tsel bleibt auf dem Bildschirm, und die Herausforderung besteht darin, die Regel zu erschlie\xdfen, die die Figuren verbindet."],["Ich bekomme die schweren immer wieder falsch. Was \xfcbersehe ich?","Meist l\xe4uft mehr als eine Regel gleichzeitig. L\xf6se jedes Merkmal einzeln, etwa Form, dann Anzahl, dann Drehung, dann Schattierung, und \xfcberpr\xfcfe deine Wahl gegen Zeile und Spalte, bevor du dich festlegst."]],variants:"Die Versionen reichen von einfachen 2x2-Rastern bis zu dichten 3x3-Matrizen mit mehreren \xfcberlagerten Regeln; manche nutzen Farbe, manche nur Schwarz-Wei\xdf. Nahe Verwandte sind Zahlen- und Buchstabenreihen, Finde-das-Andere-Aufgaben, visuelle Analogien (A verh\xe4lt sich zu B wie C zu ?) und Figurenfalt-Aufgaben, alle auf derselben Finde-die-Regel-Idee aufgebaut."},pt:{about:"Padr\xf5es: Racioc\xednio mostra uma grade de figuras abstratas com uma c\xe9lula deixada em branco, mais uma fileira de respostas candidatas. Sua tarefa \xe9 descobrir a regra oculta que governa como as figuras mudam ao longo das linhas e colunas e, ent\xe3o, escolher a \xfanica op\xe7\xe3o que completa o padr\xe3o.",benefit:"Ele exercita o racioc\xednio fluido e n\xe3o verbal: perceber rela\xe7\xf5es, manter v\xe1rias regras na cabe\xe7a ao mesmo tempo e inferir a l\xf3gica por tr\xe1s de uma sequ\xeancia sem palavras nem conhecimento pr\xe9vio. Tamb\xe9m se apoia na mem\xf3ria de trabalho e na an\xe1lise visual sistem\xe1tica.",history:"O formato de matriz remonta \xe0s Matrizes Progressivas de Raven, descritas pela primeira vez num artigo de 1936 e publicadas como teste em 1938. Por n\xe3o exigir linguagem e ser r\xe1pido de aplicar, espalhou-se depressa: a partir de 1942, todo recruta das for\xe7as armadas brit\xe2nicas fazia uma vers\xe3o curta, e testes de matriz semelhantes passaram depois a ser usados em servi\xe7os de conscri\xe7\xe3o pelo mundo todo, inclusive na Uni\xe3o Sovi\xe9tica. Desde ent\xe3o, esse estilo de quebra-cabe\xe7a virou item b\xe1sico de testes de QI, avalia\xe7\xf5es escolares e aplicativos de treino cerebral.",creator:"O ancestral padr\xe3o s\xe3o as Matrizes Progressivas de Raven, concebidas pelo psic\xf3logo brit\xe2nico John C. Raven junto com o geneticista Lionel Penrose em 1936. O quebra-cabe\xe7a de completar matrizes em si \xe9 hoje um formato gen\xe9rico com in\xfameras variantes, ent\xe3o ningu\xe9m \xe9 dono do tipo que voc\xea v\xea aqui, mas a linhagem leva direto ao trabalho original de Raven.",methods:"Leia a matriz uma dimens\xe3o de cada vez: pergunte primeiro o que muda da esquerda para a direita numa linha, depois o que muda de cima para baixo numa coluna e s\xf3 ent\xe3o combine as duas. Acompanhe cada atributo separadamente, como forma, quantidade, tamanho, rota\xe7\xe3o, sombreamento e posi\xe7\xe3o. Elimine as op\xe7\xf5es que violam qualquer regra, em vez de ca\xe7ar a que parece certa, e, nos itens dif\xedceis, confira sua resposta contra a regra da linha e a regra da coluna.",duration:"Conjuntos curtos e focados funcionam melhor: de 10 a 15 minutos, algumas vezes por semana. Pare quando os itens come\xe7arem a parecer chute, pois o cansa\xe7o transforma o racioc\xednio em adivinha\xe7\xe3o de padr\xe3o e voc\xea deixa de aprender.",research:"O achado s\xf3lido \xe9 o nada surpreendente: com pr\xe1tica voc\xea fica melhor nos pr\xf3prios quebra-cabe\xe7as de matriz, e fazer o teste repetidamente eleva de forma confi\xe1vel sua pontua\xe7\xe3o nesse tipo de tarefa, mesmo sem instru\xe7\xe3o. Se esse ganho reflete um racioc\xednio geral mais afiado ou apenas uma estrat\xe9gia melhor de fazer provas \xe9 objeto de debate, e a alega\xe7\xe3o mais forte, de que treinar racioc\xednio abstrato eleva amplamente a intelig\xeancia fluida ou o QI, \xe9 fraca. O famoso resultado de que o treino de dual n-back melhora o racioc\xednio com matrizes em grande parte n\xe3o se replicou, ent\xe3o trate qualquer promessa de aumento de intelig\xeancia geral com cautela.",rec:"V\xe1 com calma nos itens dif\xedceis e diga a regra em voz alta antes de tocar; verbalizar a l\xf3gica pega erros que o reconhecimento r\xe1pido de padr\xf5es deixa passar.",faq:[["Isso vai aumentar meu QI?","Honestamente, provavelmente n\xe3o em nenhum sentido geral. Voc\xea vai ficar visivelmente melhor em quebra-cabe\xe7as de matriz e tarefas de racioc\xednio parecidas, mas a evid\xeancia de que a habilidade se espalha para uma intelig\xeancia ampla, do mundo real, \xe9 fraca, ent\xe3o n\xe3o prometemos aumento de QI."],["Em que isso difere de um jogo de mem\xf3ria?","Jogos de mem\xf3ria testam o que voc\xea consegue reter e relembrar; este testa o que voc\xea consegue inferir. Nada precisa ser memorizado: o quebra-cabe\xe7a inteiro fica na tela e o desafio \xe9 deduzir a regra que conecta as figuras."],["Eu vivo errando os dif\xedceis. O que estou deixando passar?","Geralmente h\xe1 mais de uma regra rodando ao mesmo tempo. Resolva cada atributo separadamente, como forma, depois quantidade, depois rota\xe7\xe3o, depois sombreamento, e confira sua escolha contra a linha e a coluna antes de confirmar."]],variants:"As vers\xf5es v\xe3o de simples grades 2x2 at\xe9 densas matrizes 3x3 com v\xe1rias regras sobrepostas; algumas usam cor, outras s\xf3 preto e branco. Parentes pr\xf3ximos incluem s\xe9ries de n\xfameros e letras, conjuntos de achar o intruso, analogias visuais (A est\xe1 para B assim como C est\xe1 para ?) e tarefas de dobrar figuras, todas constru\xeddas sobre a mesma ideia de descobrir a regra."},hi:{about:"Patterns: Reasoning \u0906\u092a\u0915\u094b \u0905\u092e\u0942\u0930\u094d\u0924 \u0906\u0915\u0943\u0924\u093f\u092f\u094b\u0902 \u0915\u093e \u090f\u0915 \u0917\u094d\u0930\u093f\u0921 \u0926\u093f\u0916\u093e\u0924\u093e \u0939\u0948 \u091c\u093f\u0938\u092e\u0947\u0902 \u090f\u0915 \u0916\u093e\u0928\u093e \u0916\u093e\u0932\u0940 \u091b\u094b\u0921\u093c\u093e \u0939\u094b\u0924\u093e \u0939\u0948, \u0938\u093e\u0925 \u0939\u0940 \u0938\u0902\u092d\u093e\u0935\u093f\u0924 \u0909\u0924\u094d\u0924\u0930\u094b\u0902 \u0915\u0940 \u090f\u0915 \u092a\u0902\u0915\u094d\u0924\u093f \u0939\u094b\u0924\u0940 \u0939\u0948\u0964 \u0906\u092a\u0915\u093e \u0915\u093e\u092e \u092f\u0939 \u092a\u0924\u093e \u0932\u0917\u093e\u0928\u093e \u0939\u0948 \u0915\u093f \u0935\u0939 \u091b\u093f\u092a\u093e \u0939\u0941\u0906 \u0928\u093f\u092f\u092e \u0915\u094d\u092f\u093e \u0939\u0948 \u091c\u094b \u0924\u092f \u0915\u0930\u0924\u093e \u0939\u0948 \u0915\u093f \u092a\u0902\u0915\u094d\u0924\u093f\u092f\u094b\u0902 \u0914\u0930 \u0938\u094d\u0924\u0902\u092d\u094b\u0902 \u092e\u0947\u0902 \u0906\u0915\u0943\u0924\u093f\u092f\u093e\u0901 \u0915\u0948\u0938\u0947 \u092c\u0926\u0932\u0924\u0940 \u0939\u0948\u0902, \u0914\u0930 \u092b\u093f\u0930 \u0935\u0939 \u0905\u0915\u0947\u0932\u093e \u0935\u093f\u0915\u0932\u094d\u092a \u091a\u0941\u0928\u0928\u093e \u0939\u0948 \u091c\u094b \u092a\u0948\u091f\u0930\u094d\u0928 \u0915\u094b \u092a\u0942\u0930\u093e \u0915\u0930\u0924\u093e \u0939\u0948\u0964",benefit:"\u092f\u0939 \u0917\u0948\u0930-\u092e\u094c\u0916\u093f\u0915, \u0924\u0930\u0932 \u0924\u0930\u094d\u0915\u0936\u0915\u094d\u0924\u093f \u0915\u0940 \u0915\u0938\u0930\u0924 \u0915\u0930\u093e\u0924\u093e \u0939\u0948: \u0930\u093f\u0936\u094d\u0924\u094b\u0902 \u0915\u094b \u092a\u0939\u091a\u093e\u0928\u0928\u093e, \u090f\u0915 \u0938\u093e\u0925 \u0915\u0908 \u0928\u093f\u092f\u092e\u094b\u0902 \u0915\u094b \u0926\u093f\u092e\u093e\u0917 \u092e\u0947\u0902 \u0925\u093e\u092e\u0947 \u0930\u0916\u0928\u093e, \u0914\u0930 \u092c\u093f\u0928\u093e \u0915\u093f\u0938\u0940 \u0936\u092c\u094d\u0926 \u092f\u093e \u092a\u0942\u0930\u094d\u0935-\u091c\u094d\u091e\u093e\u0928 \u0915\u0947 \u0915\u093f\u0938\u0940 \u0915\u094d\u0930\u092e \u0915\u0947 \u092a\u0940\u091b\u0947 \u0915\u093e \u0924\u0930\u094d\u0915 \u092d\u093e\u0901\u092a \u0932\u0947\u0928\u093e\u0964 \u092f\u0939 \u0935\u0930\u094d\u0915\u093f\u0902\u0917 \u092e\u0947\u092e\u094b\u0930\u0940 \u0914\u0930 \u0935\u094d\u092f\u0935\u0938\u094d\u0925\u093f\u0924 \u0926\u0943\u0936\u094d\u092f-\u0935\u093f\u0936\u094d\u0932\u0947\u0937\u0923 \u092a\u0930 \u092d\u0940 \u091f\u093f\u0915\u093e \u0939\u0948\u0964",history:"\u092f\u0939 \u092e\u0948\u091f\u094d\u0930\u093f\u0915\u094d\u0938 \u092a\u094d\u0930\u093e\u0930\u0942\u092a \u0930\u0947\u0935\u0947\u0928\u094d\u0938 \u092a\u094d\u0930\u094b\u0917\u094d\u0930\u0947\u0938\u093f\u0935 \u092e\u0948\u091f\u094d\u0930\u093f\u0938\u0947\u0938 \u0924\u0915 \u091c\u093e\u0924\u093e \u0939\u0948, \u091c\u093f\u0938\u0915\u093e \u092a\u0939\u0932\u0940 \u092c\u093e\u0930 1936 \u0915\u0947 \u090f\u0915 \u0936\u094b\u0927-\u092a\u0924\u094d\u0930 \u092e\u0947\u0902 \u0935\u0930\u094d\u0923\u0928 \u0939\u0941\u0906 \u0914\u0930 1938 \u092e\u0947\u0902 \u0907\u0938\u0947 \u090f\u0915 \u092a\u0930\u0940\u0915\u094d\u0937\u0923 \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u092a\u094d\u0930\u0915\u093e\u0936\u093f\u0924 \u0915\u093f\u092f\u093e \u0917\u092f\u093e\u0964 \u091a\u0942\u0901\u0915\u093f \u0907\u0938\u092e\u0947\u0902 \u092d\u093e\u0937\u093e \u0915\u0940 \u091c\u093c\u0930\u0942\u0930\u0924 \u0928\u0939\u0940\u0902 \u0939\u094b\u0924\u0940 \u0914\u0930 \u0907\u0938\u0947 \u091c\u0932\u094d\u0926\u0940 \u0915\u0930\u093e\u092f\u093e \u091c\u093e \u0938\u0915\u0924\u093e \u0939\u0948, \u092f\u0939 \u0924\u0947\u091c\u093c\u0940 \u0938\u0947 \u092b\u0948\u0932\u093e: 1942 \u0938\u0947 \u092c\u094d\u0930\u093f\u091f\u093f\u0936 \u0938\u0936\u0938\u094d\u0924\u094d\u0930 \u092c\u0932\u094b\u0902 \u0915\u0947 \u0939\u0930 \u092d\u0930\u094d\u0924\u0940 \u0939\u094b\u0928\u0947 \u0935\u093e\u0932\u0947 \u0928\u0947 \u0907\u0938\u0915\u093e \u090f\u0915 \u091b\u094b\u091f\u093e \u0930\u0942\u092a \u0926\u093f\u092f\u093e, \u0914\u0930 \u092c\u093e\u0926 \u092e\u0947\u0902 \u0910\u0938\u0947 \u0939\u0940 \u092e\u0948\u091f\u094d\u0930\u093f\u0915\u094d\u0938 \u092a\u0930\u0940\u0915\u094d\u0937\u0923 \u0938\u094b\u0935\u093f\u092f\u0924 \u0938\u0902\u0918 \u0938\u092e\u0947\u0924 \u0926\u0941\u0928\u093f\u092f\u093e \u092d\u0930 \u0915\u0940 \u092d\u0930\u094d\u0924\u0940 \u0938\u0947\u0935\u093e\u0913\u0902 \u092e\u0947\u0902 \u091a\u0932\u0947\u0964 \u0924\u092c \u0938\u0947 \u092f\u0939 \u092a\u0939\u0947\u0932\u0940-\u0936\u0948\u0932\u0940 IQ \u092a\u0930\u0940\u0915\u094d\u0937\u0923\u094b\u0902, \u0938\u094d\u0915\u0942\u0932\u0940 \u0906\u0915\u0932\u0928\u094b\u0902 \u0914\u0930 \u0926\u093f\u092e\u093e\u0917\u0940-\u0915\u0938\u0930\u0924 \u0910\u092a\u094d\u0938 \u0915\u093e \u0905\u0928\u093f\u0935\u093e\u0930\u094d\u092f \u0939\u093f\u0938\u094d\u0938\u093e \u092c\u0928 \u0917\u0908 \u0939\u0948\u0964",creator:"\u092e\u093e\u0928\u0915 \u092a\u0942\u0930\u094d\u0935\u091c \u0930\u0947\u0935\u0947\u0928\u094d\u0938 \u092a\u094d\u0930\u094b\u0917\u094d\u0930\u0947\u0938\u093f\u0935 \u092e\u0948\u091f\u094d\u0930\u093f\u0938\u0947\u0938 \u0939\u0948, \u091c\u093f\u0938\u0947 \u092c\u094d\u0930\u093f\u091f\u093f\u0936 \u092e\u0928\u094b\u0935\u0948\u091c\u094d\u091e\u093e\u0928\u093f\u0915 \u091c\u0949\u0928 \u0938\u0940. \u0930\u0947\u0935\u0947\u0928 \u0928\u0947 \u0906\u0928\u0941\u0935\u0902\u0936\u093f\u0915\u0940\u0935\u093f\u0926\u094d \u0932\u093e\u092f\u094b\u0928\u0947\u0932 \u092a\u0947\u0928\u0930\u094b\u091c\u093c \u0915\u0947 \u0938\u093e\u0925 \u092e\u093f\u0932\u0915\u0930 1936 \u092e\u0947\u0902 \u0930\u091a\u093e\u0964 \u092e\u0948\u091f\u094d\u0930\u093f\u0915\u094d\u0938-\u092a\u0942\u0930\u094d\u0924\u093f \u092a\u0939\u0947\u0932\u0940 \u0905\u092c \u0905\u0928\u0917\u093f\u0928\u0924 \u0930\u0942\u092a\u094b\u0902 \u0935\u093e\u0932\u093e \u090f\u0915 \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u092a\u094d\u0930\u093e\u0930\u0942\u092a \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u091c\u094b \u0906\u092a \u092f\u0939\u093e\u0901 \u0926\u0947\u0916\u0924\u0947 \u0939\u0948\u0902 \u0909\u0938 \u092a\u0930 \u0915\u093f\u0938\u0940 \u090f\u0915 \u0935\u094d\u092f\u0915\u094d\u0924\u093f \u0915\u093e \u0905\u0927\u093f\u0915\u093e\u0930 \u0928\u0939\u0940\u0902, \u092a\u0930 \u0907\u0938\u0915\u0940 \u0935\u0902\u0936-\u092a\u0930\u0902\u092a\u0930\u093e \u0938\u0940\u0927\u0947 \u0930\u0947\u0935\u0947\u0928 \u0915\u0947 \u092e\u0942\u0932 \u0915\u093e\u092e \u0924\u0915 \u091c\u093e\u0924\u0940 \u0939\u0948\u0964",methods:"\u092e\u0948\u091f\u094d\u0930\u093f\u0915\u094d\u0938 \u0915\u094b \u090f\u0915 \u092c\u093e\u0930 \u092e\u0947\u0902 \u090f\u0915 \u0939\u0940 \u0926\u093f\u0936\u093e \u092e\u0947\u0902 \u092a\u0922\u093c\u0947\u0902: \u092a\u0939\u0932\u0947 \u092a\u0942\u091b\u0947\u0902 \u0915\u093f \u0915\u093f\u0938\u0940 \u092a\u0902\u0915\u094d\u0924\u093f \u092e\u0947\u0902 \u092c\u093e\u090f\u0901 \u0938\u0947 \u0926\u093e\u090f\u0901 \u0915\u094d\u092f\u093e \u092c\u0926\u0932\u0924\u093e \u0939\u0948, \u092b\u093f\u0930 \u0915\u093f \u0915\u093f\u0938\u0940 \u0938\u094d\u0924\u0902\u092d \u092e\u0947\u0902 \u090a\u092a\u0930 \u0938\u0947 \u0928\u0940\u091a\u0947 \u0915\u094d\u092f\u093e \u092c\u0926\u0932\u0924\u093e \u0939\u0948, \u0914\u0930 \u0909\u0938\u0915\u0947 \u092c\u093e\u0926 \u0939\u0940 \u0926\u094b\u0928\u094b\u0902 \u0915\u094b \u091c\u094b\u0921\u093c\u0947\u0902\u0964 \u0939\u0930 \u0935\u093f\u0936\u0947\u0937\u0924\u093e \u0915\u094b \u0905\u0932\u0917-\u0905\u0932\u0917 \u091f\u094d\u0930\u0948\u0915 \u0915\u0930\u0947\u0902 \u2014 \u091c\u0948\u0938\u0947 \u0906\u0915\u093e\u0930, \u0938\u0902\u0916\u094d\u092f\u093e, \u092e\u093e\u092a, \u0918\u0941\u092e\u093e\u0935, \u091b\u093e\u092f\u093e\u0902\u0915\u0928 \u0914\u0930 \u0938\u094d\u0925\u093f\u0924\u093f\u0964 '\u091c\u094b \u0938\u0939\u0940 \u0926\u093f\u0916\u0947' \u0909\u0938\u0947 \u0922\u0942\u0901\u0922\u093c\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u0909\u0928 \u0935\u093f\u0915\u0932\u094d\u092a\u094b\u0902 \u0915\u094b \u0939\u091f\u093e\u090f\u0901 \u091c\u094b \u0915\u093f\u0938\u0940 \u0928\u093f\u092f\u092e \u0915\u094b \u0924\u094b\u0921\u093c\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u0915\u0920\u093f\u0928 \u092a\u094d\u0930\u0936\u094d\u0928\u094b\u0902 \u092e\u0947\u0902 \u0905\u092a\u0928\u0947 \u0909\u0924\u094d\u0924\u0930 \u0915\u094b \u092a\u0902\u0915\u094d\u0924\u093f-\u0928\u093f\u092f\u092e \u0914\u0930 \u0938\u094d\u0924\u0902\u092d-\u0928\u093f\u092f\u092e \u0926\u094b\u0928\u094b\u0902 \u0915\u0947 \u0935\u093f\u0930\u0941\u0926\u094d\u0927 \u091c\u093e\u0901\u091a\u0947\u0902\u0964",duration:"\u091b\u094b\u091f\u0947, \u090f\u0915\u093e\u0917\u094d\u0930 \u0938\u0947\u091f \u0938\u092c\u0938\u0947 \u0905\u091a\u094d\u091b\u0947 \u0930\u0939\u0924\u0947 \u0939\u0948\u0902: \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u0915\u0941\u091b \u092c\u093e\u0930 10 \u0938\u0947 15 \u092e\u093f\u0928\u091f\u0964 \u091c\u092c \u092a\u094d\u0930\u0936\u094d\u0928 \u0905\u0902\u0926\u093e\u091c\u093c\u0947\u092c\u093e\u091c\u093c\u0940 \u091c\u0948\u0938\u0947 \u0932\u0917\u0928\u0947 \u0932\u0917\u0947\u0902 \u0924\u094b \u0930\u0941\u0915 \u091c\u093e\u090f\u0901, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u0925\u0915\u093e\u0928 \u0924\u0930\u094d\u0915 \u0915\u094b \u092a\u0948\u091f\u0930\u094d\u0928-\u0905\u0928\u0941\u092e\u093e\u0928 \u092e\u0947\u0902 \u092c\u0926\u0932 \u0926\u0947\u0924\u0940 \u0939\u0948 \u0914\u0930 \u0906\u092a \u0938\u0940\u0916\u0928\u093e \u092c\u0902\u0926 \u0915\u0930 \u0926\u0947\u0924\u0947 \u0939\u0948\u0902\u0964",research:"\u0920\u094b\u0938 \u0928\u093f\u0937\u094d\u0915\u0930\u094d\u0937 \u0935\u0939\u0940 \u091a\u094c\u0902\u0915\u093e\u0928\u0947 \u0935\u093e\u0932\u0940 \u092c\u093e\u0924 \u0928\u0939\u0940\u0902 \u0939\u0948: \u0905\u092d\u094d\u092f\u093e\u0938 \u0938\u0947 \u0906\u092a \u092e\u0948\u091f\u094d\u0930\u093f\u0915\u094d\u0938 \u092a\u0939\u0947\u0932\u093f\u092f\u094b\u0902 \u092e\u0947\u0902 \u0916\u093c\u0941\u0926 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u092c\u093e\u0930-\u092c\u093e\u0930 \u092a\u0930\u0940\u0915\u094d\u0937\u0923 \u0926\u0947\u0928\u0947 \u0938\u0947 \u092c\u093f\u0928\u093e \u0915\u093f\u0938\u0940 \u0915\u094b\u091a\u093f\u0902\u0917 \u0915\u0947 \u092d\u0940 \u0907\u0938 \u0924\u0930\u0939 \u0915\u0947 \u0915\u093e\u092e\u094b\u0902 \u092e\u0947\u0902 \u0906\u092a\u0915\u093e \u0938\u094d\u0915\u094b\u0930 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0922\u0902\u0917 \u0938\u0947 \u092c\u0922\u093c\u0924\u093e \u0939\u0948\u0964 \u092f\u0939 \u092b\u093c\u093e\u092f\u0926\u093e \u0924\u0947\u091c\u093c \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u0924\u0930\u094d\u0915\u0936\u0915\u094d\u0924\u093f \u0915\u093e \u0928\u0924\u0940\u091c\u093e \u0939\u0948 \u092f\u093e \u0915\u0947\u0935\u0932 \u092c\u0947\u0939\u0924\u0930 \u092a\u0930\u0940\u0915\u094d\u0937\u093e-\u0926\u0947\u0928\u0947 \u0915\u0940 \u0930\u0923\u0928\u0940\u0924\u093f \u0915\u093e, \u0907\u0938 \u092a\u0930 \u092c\u0939\u0938 \u0939\u0948, \u0914\u0930 \u0938\u092c\u0938\u0947 \u092c\u0921\u093c\u093e \u0926\u093e\u0935\u093e \u2014 \u0915\u093f \u0905\u092e\u0942\u0930\u094d\u0924 \u0924\u0930\u094d\u0915 \u0915\u093e \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u0935\u094d\u092f\u093e\u092a\u0915 \u0930\u0942\u092a \u0938\u0947 \u0924\u0930\u0932 \u092c\u0941\u0926\u094d\u0927\u093f \u092f\u093e IQ \u092c\u0922\u093c\u093e\u0924\u093e \u0939\u0948 \u2014 \u0915\u092e\u091c\u093c\u094b\u0930 \u0939\u0948\u0964 \u092f\u0939 \u092e\u0936\u0939\u0942\u0930 \u0928\u0924\u0940\u091c\u093e \u0915\u093f \u0921\u094d\u092f\u0942\u0932 n-\u092c\u0948\u0915 \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u092e\u0948\u091f\u094d\u0930\u093f\u0915\u094d\u0938 \u0924\u0930\u094d\u0915 \u0915\u094b \u092c\u0922\u093c\u093e\u0924\u093e \u0939\u0948, \u092c\u0921\u093c\u0947 \u092a\u0948\u092e\u093e\u0928\u0947 \u092a\u0930 \u0926\u094b\u092c\u093e\u0930\u093e \u0938\u093f\u0926\u094d\u0927 \u0928\u0939\u0940\u0902 \u0939\u094b \u092a\u093e\u092f\u093e, \u0907\u0938\u0932\u093f\u090f \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u092c\u0941\u0926\u094d\u0927\u093f \u092c\u0922\u093c\u0928\u0947 \u0915\u0947 \u0915\u093f\u0938\u0940 \u092d\u0940 \u0935\u093e\u0926\u0947 \u0915\u094b \u0938\u093e\u0935\u0927\u093e\u0928\u0940 \u0938\u0947 \u0932\u0947\u0902\u0964",rec:"\u0915\u0920\u093f\u0928 \u092a\u094d\u0930\u0936\u094d\u0928\u094b\u0902 \u092a\u0930 \u0930\u092b\u093c\u094d\u0924\u093e\u0930 \u0927\u0940\u092e\u0940 \u0915\u0930\u0947\u0902 \u0914\u0930 \u091f\u0948\u092a \u0915\u0930\u0928\u0947 \u0938\u0947 \u092a\u0939\u0932\u0947 \u0928\u093f\u092f\u092e \u0915\u094b \u091c\u093c\u094b\u0930 \u0938\u0947 \u092c\u094b\u0932\u0915\u0930 \u092c\u0924\u093e\u090f\u0901; \u0924\u0930\u094d\u0915 \u0915\u094b \u0936\u092c\u094d\u0926\u094b\u0902 \u092e\u0947\u0902 \u0915\u0939\u0928\u0947 \u0938\u0947 \u0935\u0947 \u0917\u0932\u0924\u093f\u092f\u093e\u0901 \u092a\u0915\u0921\u093c \u092e\u0947\u0902 \u0906 \u091c\u093e\u0924\u0940 \u0939\u0948\u0902 \u091c\u094b \u0924\u0947\u091c\u093c \u092a\u0948\u091f\u0930\u094d\u0928-\u092e\u093f\u0932\u093e\u0928 \u0938\u0947 \u091b\u0942\u091f \u091c\u093e\u0924\u0940 \u0939\u0948\u0902\u0964",faq:[["\u0915\u094d\u092f\u093e \u0907\u0938\u0938\u0947 \u092e\u0947\u0930\u093e IQ \u092c\u0922\u093c\u0947\u0917\u093e?","\u0938\u091a \u0915\u0939\u0947\u0902 \u0924\u094b \u0915\u093f\u0938\u0940 \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u0905\u0930\u094d\u0925 \u092e\u0947\u0902 \u0936\u093e\u092f\u0926 \u0928\u0939\u0940\u0902\u0964 \u0906\u092a \u092e\u0948\u091f\u094d\u0930\u093f\u0915\u094d\u0938 \u092a\u0939\u0947\u0932\u093f\u092f\u094b\u0902 \u0914\u0930 \u0907\u0938 \u091c\u0948\u0938\u0947 \u0924\u0930\u094d\u0915-\u0915\u093e\u092e\u094b\u0902 \u092e\u0947\u0902 \u0938\u093e\u092b\u093c \u0924\u094c\u0930 \u092a\u0930 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u090f\u0901\u0917\u0947, \u092a\u0930 \u0907\u0938\u0915\u093e \u092a\u094d\u0930\u092e\u093e\u0923 \u0915\u093f \u092f\u0939 \u0915\u094c\u0936\u0932 \u0935\u094d\u092f\u093e\u092a\u0915, \u0905\u0938\u0932\u0940-\u0926\u0941\u0928\u093f\u092f\u093e \u0915\u0940 \u092c\u0941\u0926\u094d\u0927\u093f \u0924\u0915 \u092b\u0948\u0932\u0924\u093e \u0939\u0948, \u0915\u092e\u091c\u093c\u094b\u0930 \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0939\u092e IQ \u092c\u0922\u093c\u0928\u0947 \u0915\u093e \u0935\u093e\u0926\u093e \u0928\u0939\u0940\u0902 \u0915\u0930\u0924\u0947\u0964"],["\u092f\u0939 \u0938\u094d\u092e\u0943\u0924\u093f \u0935\u093e\u0932\u0947 \u0916\u0947\u0932 \u0938\u0947 \u0915\u0948\u0938\u0947 \u0905\u0932\u0917 \u0939\u0948?","\u0938\u094d\u092e\u0943\u0924\u093f \u0935\u093e\u0932\u0947 \u0916\u0947\u0932 \u091c\u093e\u0901\u091a\u0924\u0947 \u0939\u0948\u0902 \u0915\u093f \u0906\u092a \u0915\u094d\u092f\u093e \u0925\u093e\u092e\u0947 \u0914\u0930 \u092f\u093e\u0926 \u0930\u0916 \u0938\u0915\u0924\u0947 \u0939\u0948\u0902; \u092f\u0939 \u091c\u093e\u0901\u091a\u0924\u093e \u0939\u0948 \u0915\u093f \u0906\u092a \u0915\u094d\u092f\u093e \u092d\u093e\u0901\u092a \u0938\u0915\u0924\u0947 \u0939\u0948\u0902\u0964 \u0915\u0941\u091b \u092d\u0940 \u092f\u093e\u0926 \u0928\u0939\u0940\u0902 \u0930\u0916\u0928\u093e \u0939\u094b\u0924\u093e \u2014 \u092a\u0942\u0930\u0940 \u092a\u0939\u0947\u0932\u0940 \u0938\u094d\u0915\u094d\u0930\u0940\u0928 \u092a\u0930 \u0939\u0940 \u0930\u0939\u0924\u0940 \u0939\u0948 \u0914\u0930 \u091a\u0941\u0928\u094c\u0924\u0940 \u0939\u0948 \u0909\u0938 \u0928\u093f\u092f\u092e \u0915\u094b \u0924\u0930\u094d\u0915 \u0938\u0947 \u0928\u093f\u0915\u093e\u0932\u0928\u093e \u091c\u094b \u0906\u0915\u0943\u0924\u093f\u092f\u094b\u0902 \u0915\u094b \u091c\u094b\u0921\u093c\u0924\u093e \u0939\u0948\u0964"],["\u092e\u0948\u0902 \u0915\u0920\u093f\u0928 \u0935\u093e\u0932\u0947 \u092c\u093e\u0930-\u092c\u093e\u0930 \u0917\u0932\u0924 \u0915\u0930 \u092c\u0948\u0920\u0924\u093e \u0939\u0942\u0901\u0964 \u092e\u0941\u091d\u0938\u0947 \u0915\u094d\u092f\u093e \u091b\u0942\u091f \u0930\u0939\u093e \u0939\u0948?","\u0906\u092e\u0924\u094c\u0930 \u092a\u0930 \u090f\u0915 \u0938\u093e\u0925 \u090f\u0915 \u0938\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0928\u093f\u092f\u092e \u091a\u0932 \u0930\u0939\u0947 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902\u0964 \u0939\u0930 \u0935\u093f\u0936\u0947\u0937\u0924\u093e \u0915\u094b \u0905\u0932\u0917-\u0905\u0932\u0917 \u0939\u0932 \u0915\u0930\u0947\u0902 \u2014 \u091c\u0948\u0938\u0947 \u092a\u0939\u0932\u0947 \u0906\u0915\u093e\u0930, \u092b\u093f\u0930 \u0938\u0902\u0916\u094d\u092f\u093e, \u092b\u093f\u0930 \u0918\u0941\u092e\u093e\u0935, \u092b\u093f\u0930 \u091b\u093e\u092f\u093e\u0902\u0915\u0928 \u2014 \u0914\u0930 \u0924\u092f \u0915\u0930\u0928\u0947 \u0938\u0947 \u092a\u0939\u0932\u0947 \u0905\u092a\u0928\u0947 \u091a\u0941\u0928\u093e\u0935 \u0915\u094b \u092a\u0902\u0915\u094d\u0924\u093f \u0914\u0930 \u0938\u094d\u0924\u0902\u092d \u0926\u094b\u0928\u094b\u0902 \u0915\u0947 \u0935\u093f\u0930\u0941\u0926\u094d\u0927 \u0938\u0924\u094d\u092f\u093e\u092a\u093f\u0924 \u0915\u0930\u0947\u0902\u0964"]],variants:"\u0930\u0942\u092a \u0938\u0930\u0932 2x2 \u0917\u094d\u0930\u093f\u0921 \u0938\u0947 \u0932\u0947\u0915\u0930 \u0915\u0908 \u0906\u092a\u0938 \u092e\u0947\u0902 \u0917\u0941\u0901\u0925\u0947 \u0928\u093f\u092f\u092e\u094b\u0902 \u0935\u093e\u0932\u0947 \u0918\u0928\u0947 3x3 \u092e\u0948\u091f\u094d\u0930\u093f\u0915\u094d\u0938 \u0924\u0915 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902; \u0915\u0941\u091b \u0930\u0902\u0917 \u0915\u093e \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902, \u0915\u0941\u091b \u0915\u0947\u0935\u0932 \u0915\u093e\u0932\u0947-\u0938\u092b\u093c\u0947\u0926 \u0915\u0947\u0964 \u0928\u093f\u0915\u091f \u0915\u0947 \u0930\u093f\u0936\u094d\u0924\u0947\u0926\u093e\u0930\u094b\u0902 \u092e\u0947\u0902 \u0938\u0902\u0916\u094d\u092f\u093e \u0914\u0930 \u0905\u0915\u094d\u0937\u0930 \u0936\u094d\u0930\u0943\u0902\u0916\u0932\u093e\u090f\u0901, \u092c\u0947\u092e\u0947\u0932-\u0915\u094b-\u0922\u0942\u0901\u0922\u093c\u094b \u0938\u0947\u091f, \u0926\u0943\u0936\u094d\u092f \u0909\u092a\u092e\u093e\u090f\u0901 (A \u0915\u093e B \u0938\u0947 \u0935\u0939\u0940 \u0938\u0902\u092c\u0902\u0927 \u091c\u094b C \u0915\u093e ? \u0938\u0947) \u0914\u0930 \u0906\u0915\u0943\u0924\u093f-\u092e\u094b\u0921\u093c\u0928\u0947 \u0935\u093e\u0932\u0947 \u0915\u093e\u092e \u0936\u093e\u092e\u093f\u0932 \u0939\u0948\u0902, \u091c\u094b \u0938\u092c \u0909\u0938\u0940 \u0928\u093f\u092f\u092e-\u0916\u094b\u091c\u094b \u0935\u093f\u091a\u093e\u0930 \u092a\u0930 \u092c\u0928\u0947 \u0939\u0948\u0902\u0964"},zh:{about:"\u300c\u56fe\u5f62\u63a8\u7406\u300d\u4f1a\u7ed9\u4f60\u5448\u73b0\u4e00\u4e2a\u7531\u62bd\u8c61\u56fe\u5f62\u7ec4\u6210\u7684\u7f51\u683c\uff0c\u5176\u4e2d\u7559\u6709\u4e00\u4e2a\u7a7a\u683c\uff0c\u518d\u52a0\u4e0a\u4e00\u6392\u5019\u9009\u7b54\u6848\u3002\u4f60\u7684\u4efb\u52a1\u662f\u63a8\u65ad\u51fa\u652f\u914d\u8fd9\u4e9b\u56fe\u5f62\u5728\u884c\u4e0e\u5217\u4e4b\u95f4\u5982\u4f55\u53d8\u5316\u7684\u9690\u85cf\u89c4\u5219\uff0c\u7136\u540e\u9009\u51fa\u90a3\u4e2a\u552f\u4e00\u80fd\u628a\u6574\u4e2a\u56fe\u6848\u8865\u5168\u7684\u9009\u9879\u3002",benefit:"\u5b83\u953b\u70bc\u7684\u662f\u975e\u8a00\u8bed\u7684\u6d41\u4f53\u63a8\u7406\uff1a\u53d1\u73b0\u56fe\u5f62\u4e4b\u95f4\u7684\u5173\u7cfb\u3001\u540c\u65f6\u5728\u8111\u4e2d\u4fdd\u6301\u597d\u51e0\u6761\u89c4\u5219\uff0c\u5e76\u5728\u4e0d\u4f9d\u8d56\u4efb\u4f55\u6587\u5b57\u6216\u65e2\u6709\u77e5\u8bc6\u7684\u60c5\u51b5\u4e0b\uff0c\u63a8\u65ad\u51fa\u4e00\u7ec4\u5e8f\u5217\u80cc\u540e\u7684\u903b\u8f91\u3002\u5b83\u540c\u6837\u4f9d\u8d56\u5de5\u4f5c\u8bb0\u5fc6\u548c\u7cfb\u7edf\u5316\u7684\u89c6\u89c9\u5206\u6790\u3002",history:"\u8fd9\u79cd\u77e9\u9635\u9898\u578b\u53ef\u4ee5\u8ffd\u6eaf\u5230\u745e\u6587\u6e10\u8fdb\u77e9\u9635\uff08Raven's Progressive Matrices\uff09\uff0c\u5b83\u6700\u65e9\u57281936\u5e74\u7684\u4e00\u7bc7\u8bba\u6587\u4e2d\u88ab\u63cf\u8ff0\uff0c\u5e76\u4e8e1938\u5e74\u4f5c\u4e3a\u4e00\u9879\u6d4b\u9a8c\u51fa\u7248\u3002\u7531\u4e8e\u5b83\u4e0d\u9700\u8981\u8bed\u8a00\u3001\u65bd\u6d4b\u53c8\u5feb\uff0c\u56e0\u6b64\u4f20\u64ad\u5f97\u5f88\u5feb\uff1a\u4ece1942\u5e74\u8d77\uff0c\u6bcf\u4e00\u540d\u52a0\u5165\u82f1\u56fd\u6b66\u88c5\u90e8\u961f\u7684\u65b0\u5175\u90fd\u8981\u505a\u4e00\u4efd\u7b80\u77ed\u7248\u672c\uff0c\u7c7b\u4f3c\u7684\u77e9\u9635\u6d4b\u9a8c\u540e\u6765\u5728\u4e16\u754c\u5404\u56fd\u7684\u4e49\u52a1\u5175\u5f79\u5236\u5ea6\u4e2d\u63a8\u884c\uff0c\u5305\u62ec\u82cf\u8054\u3002\u6b64\u540e\uff0c\u8fd9\u79cd\u8c1c\u9898\u5f62\u5f0f\u6210\u4e86\u667a\u529b\u6d4b\u9a8c\u3001\u5b66\u6821\u6d4b\u8bc4\u548c\u5927\u8111\u8bad\u7ec3\u5e94\u7528\u4e2d\u7684\u5e38\u5ba2\u3002",creator:"\u5b83\u7684\u6807\u51c6\u6e90\u5934\u662f\u745e\u6587\u6e10\u8fdb\u77e9\u9635\uff0c\u7531\u82f1\u56fd\u5fc3\u7406\u5b66\u5bb6\u7ea6\u7ff0\xb7C\xb7\u745e\u6587\uff08John C. Raven\uff09\u4e0e\u9057\u4f20\u5b66\u5bb6\u83b1\u6602\u5185\u5c14\xb7\u5f6d\u7f57\u65af\uff08Lionel Penrose\uff09\u4e8e1936\u5e74\u5171\u540c\u8bbe\u8ba1\u3002\u77e9\u9635\u8865\u5168\u8c1c\u9898\u672c\u8eab\u5982\u4eca\u5df2\u662f\u4e00\u79cd\u901a\u7528\u7684\u9898\u578b\uff0c\u53d8\u4f53\u6570\u4e0d\u80dc\u6570\uff0c\u6240\u4ee5\u4f60\u5728\u8fd9\u91cc\u770b\u5230\u7684\u8fd9\u4e00\u79cd\u5e76\u4e0d\u5f52\u4efb\u4f55\u4e00\u4e2a\u4eba\u6240\u6709\uff0c\u4f46\u5176\u8840\u8109\u53ef\u4ee5\u4e00\u76f4\u8ffd\u6eaf\u5230\u745e\u6587\u6700\u521d\u7684\u5de5\u4f5c\u3002",methods:"\u4e00\u6b21\u53ea\u8bfb\u4e00\u4e2a\u7ef4\u5ea6\u7684\u77e9\u9635\uff1a\u5148\u95ee\u4ece\u5de6\u5230\u53f3\u3001\u6cbf\u7740\u4e00\u884c\u6709\u4ec0\u4e48\u5728\u53d8\u5316\uff0c\u518d\u95ee\u4ece\u4e0a\u5230\u4e0b\u3001\u6cbf\u7740\u4e00\u5217\u6709\u4ec0\u4e48\u5728\u53d8\u5316\uff0c\u6700\u540e\u624d\u628a\u4e24\u8005\u7ed3\u5408\u8d77\u6765\u3002\u628a\u6bcf\u4e2a\u5c5e\u6027\u5206\u5f00\u8ffd\u8e2a\uff0c\u6bd4\u5982\u5f62\u72b6\u3001\u6570\u91cf\u3001\u5927\u5c0f\u3001\u65cb\u8f6c\u3001\u660e\u6697\u548c\u4f4d\u7f6e\u3002\u8981\u6392\u9664\u4efb\u4f55\u8fdd\u53cd\u67d0\u6761\u89c4\u5219\u7684\u9009\u9879\uff0c\u800c\u4e0d\u662f\u53bb\u627e\u90a3\u4e2a\u300c\u770b\u7740\u5bf9\u300d\u7684\u9009\u9879\uff1b\u9047\u5230\u96be\u9898\u65f6\uff0c\u518d\u7528\u884c\u89c4\u5219\u548c\u5217\u89c4\u5219\u53cc\u53cc\u6838\u5bf9\u4f60\u7684\u7b54\u6848\u3002",duration:"\u77ed\u800c\u4e13\u6ce8\u7684\u9898\u7ec4\u6548\u679c\u6700\u597d\uff1a\u6bcf\u5468\u7ec3\u51e0\u6b21\u3001\u6bcf\u6b2110\u523015\u5206\u949f\u3002\u5f53\u9898\u76ee\u5f00\u59cb\u8ba9\u4f60\u89c9\u5f97\u50cf\u662f\u5728\u778e\u731c\u65f6\u5c31\u505c\u4e0b\u6765\u2014\u2014\u75b2\u52b3\u4f1a\u628a\u63a8\u7406\u53d8\u6210\u300c\u731c\u56fe\u6848\u300d\uff0c\u4f60\u4e5f\u5c31\u5b66\u4e0d\u5230\u4e1c\u897f\u4e86\u3002",research:"\u624e\u5b9e\u7684\u53d1\u73b0\u662f\u90a3\u4e2a\u5e76\u4e0d\u610f\u5916\u7684\u7ed3\u8bba\uff1a\u901a\u8fc7\u7ec3\u4e60\uff0c\u4f60\u4f1a\u66f4\u64c5\u957f\u77e9\u9635\u8c1c\u9898\u672c\u8eab\uff0c\u800c\u4e14\u5373\u4fbf\u6ca1\u6709\u4eba\u6307\u5bfc\uff0c\u53cd\u590d\u6d4b\u9a8c\u4e5f\u80fd\u53ef\u9760\u5730\u63d0\u9ad8\u4f60\u5728\u8fd9\u7c7b\u4efb\u52a1\u4e0a\u7684\u5f97\u5206\u3002\u81f3\u4e8e\u8fd9\u79cd\u8fdb\u6b65\u53cd\u6620\u7684\u662f\u66f4\u654f\u9510\u7684\u4e00\u822c\u63a8\u7406\u80fd\u529b\uff0c\u8fd8\u662f\u4ec5\u4ec5\u662f\u66f4\u597d\u7684\u5e94\u8bd5\u7b56\u7565\uff0c\u4ecd\u6709\u4e89\u8bae\uff1b\u800c\u6700\u5f3a\u7684\u90a3\u4e2a\u8bf4\u6cd5\u2014\u2014\u5373\u5e7f\u6cdb\u8bad\u7ec3\u62bd\u8c61\u63a8\u7406\u80fd\u63d0\u5347\u6d41\u4f53\u667a\u529b\u6216\u667a\u5546\u2014\u2014\u662f\u7ad9\u4e0d\u4f4f\u811a\u7684\u3002\u90a3\u4e2a\u8457\u540d\u7684\u7ed3\u8bba\uff0c\u5373\u53cc\u91cd n-back \u8bad\u7ec3\u80fd\u63d0\u5347\u77e9\u9635\u63a8\u7406\u80fd\u529b\uff0c\u5728\u5f88\u5927\u7a0b\u5ea6\u4e0a\u672a\u80fd\u88ab\u91cd\u590d\u9a8c\u8bc1\uff0c\u6240\u4ee5\u5bf9\u4efb\u4f55\u300c\u63d0\u5347\u4e00\u822c\u667a\u529b\u300d\u7684\u627f\u8bfa\u90fd\u8981\u4fdd\u6301\u8c28\u614e\u3002",rec:"\u5728\u96be\u9898\u4e0a\u653e\u6162\u901f\u5ea6\uff0c\u5728\u70b9\u9009\u4e4b\u524d\u628a\u89c4\u5219\u5927\u58f0\u8bf4\u51fa\u6765\uff1b\u628a\u903b\u8f91\u7528\u8bed\u8a00\u8bb2\u51fa\u6765\uff0c\u80fd\u6293\u4f4f\u90a3\u4e9b\u5feb\u901f\u56fe\u6848\u5339\u914d\u4f1a\u6f0f\u6389\u7684\u9519\u8bef\u3002",faq:[["\u8fd9\u4f1a\u63d0\u9ad8\u6211\u7684\u667a\u5546\u5417\uff1f","\u8001\u5b9e\u8bf4\uff0c\u4ece\u4efb\u4f55\u4e00\u822c\u610f\u4e49\u4e0a\u8bb2\uff0c\u5927\u6982\u4e0d\u4f1a\u3002\u4f60\u4f1a\u5728\u77e9\u9635\u8c1c\u9898\u548c\u7c7b\u4f3c\u7684\u63a8\u7406\u4efb\u52a1\u4e0a\u660e\u663e\u53d8\u5f3a\uff0c\u4f46\u8868\u660e\u8fd9\u9879\u6280\u80fd\u4f1a\u6269\u6563\u5230\u5e7f\u6cdb\u7684\u3001\u73b0\u5b9e\u4e16\u754c\u4e2d\u7684\u667a\u529b\u7684\u8bc1\u636e\u662f\u8584\u5f31\u7684\uff0c\u6240\u4ee5\u6211\u4eec\u4e0d\u627f\u8bfa\u80fd\u63d0\u5347\u667a\u5546\u3002"],["\u8fd9\u548c\u8bb0\u5fc6\u6e38\u620f\u6709\u4ec0\u4e48\u4e0d\u540c\uff1f","\u8bb0\u5fc6\u6e38\u620f\u8003\u7684\u662f\u4f60\u80fd\u8bb0\u4f4f\u548c\u56de\u60f3\u8d77\u591a\u5c11\u4e1c\u897f\uff1b\u800c\u8fd9\u4e2a\u8003\u7684\u662f\u4f60\u80fd\u63a8\u65ad\u51fa\u4ec0\u4e48\u3002\u5b83\u4ec0\u4e48\u90fd\u4e0d\u9700\u8981\u80cc\uff0c\u6574\u9053\u8c1c\u9898\u59cb\u7ec8\u7559\u5728\u5c4f\u5e55\u4e0a\uff0c\u96be\u70b9\u5728\u4e8e\u63a8\u7406\u51fa\u90a3\u6761\u8fde\u63a5\u5404\u4e2a\u56fe\u5f62\u7684\u89c4\u5219\u3002"],["\u90a3\u4e9b\u96be\u9898\u6211\u8001\u662f\u505a\u9519\uff0c\u6211\u5230\u5e95\u6f0f\u770b\u4e86\u4ec0\u4e48\uff1f","\u901a\u5e38\u662f\u6709\u4e0d\u6b62\u4e00\u6761\u89c4\u5219\u5728\u540c\u65f6\u8fd0\u4f5c\u3002\u628a\u6bcf\u4e2a\u5c5e\u6027\u5206\u5f00\u6765\u89e3\uff0c\u6bd4\u5982\u5148\u89e3\u5f62\u72b6\uff0c\u518d\u89e3\u6570\u91cf\uff0c\u7136\u540e\u662f\u65cb\u8f6c\uff0c\u63a5\u7740\u662f\u660e\u6697\uff0c\u6700\u540e\u5728\u786e\u5b9a\u4e4b\u524d\u7528\u884c\u89c4\u5219\u548c\u5217\u89c4\u5219\u53cc\u53cc\u6838\u5bf9\u4f60\u9009\u7684\u7b54\u6848\u3002"]],variants:"\u7248\u672c\u4ece\u7b80\u5355\u76842\xd72\u7f51\u683c\uff0c\u5230\u5bc6\u96c6\u7684\u3001\u5e26\u6709\u597d\u51e0\u6761\u76f8\u4e92\u91cd\u53e0\u89c4\u5219\u76843\xd73\u77e9\u9635\u90fd\u6709\uff1b\u6709\u7684\u7528\u5f69\u8272\uff0c\u6709\u7684\u53ea\u7528\u9ed1\u767d\u3002\u4e0e\u5b83\u76f8\u8fd1\u7684\u8fd8\u6709\uff1a\u6570\u5b57\u4e0e\u5b57\u6bcd\u5e8f\u5217\u3001\u627e\u4e0d\u540c\uff08odd-one-out\uff09\u3001\u89c6\u89c9\u7c7b\u6bd4\uff08A\u4e4b\u4e8eB\uff0c\u72b9\u5982C\u4e4b\u4e8e\uff1f\uff09\u4ee5\u53ca\u56fe\u5f62\u6298\u53e0\u4efb\u52a1\uff0c\u5b83\u4eec\u5168\u90fd\u5efa\u7acb\u5728\u540c\u4e00\u4e2a\u300c\u627e\u89c4\u5219\u300d\u7684\u601d\u8def\u4e4b\u4e0a\u3002"}},"phonemic-fluency":{ru:{about:"\u0424\u043e\u043d\u0435\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u0430\u044f \u0431\u0435\u0433\u043b\u043e\u0441\u0442\u044c \u2014 \u044d\u0442\u043e \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u0435 \u043d\u0430 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u043f\u043e\u0434\u0431\u043e\u0440\u0430 \u0441\u043b\u043e\u0432: \u0432\u0430\u043c \u0434\u0430\u044e\u0442 \u043e\u0434\u043d\u0443 \u0431\u0443\u043a\u0432\u0443, \u0438 \u0437\u0430 \u0444\u0438\u043a\u0441\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u043e\u0435 \u0432\u0440\u0435\u043c\u044f (\u043e\u0431\u044b\u0447\u043d\u043e 60 \u0441\u0435\u043a\u0443\u043d\u0434) \u043d\u0443\u0436\u043d\u043e \u043d\u0430\u0437\u0432\u0430\u0442\u044c \u0438\u043b\u0438 \u043d\u0430\u043f\u0435\u0447\u0430\u0442\u0430\u0442\u044c \u043a\u0430\u043a \u043c\u043e\u0436\u043d\u043e \u0431\u043e\u043b\u044c\u0448\u0435 \u0441\u043b\u043e\u0432, \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u0441 \u043d\u0435\u0451 \u043d\u0430\u0447\u0438\u043d\u0430\u044e\u0442\u0441\u044f. \u0418\u043c\u0435\u043d\u0430 \u0441\u043e\u0431\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0435, \u0447\u0438\u0441\u043b\u0430 \u0438 \u043f\u043e\u0432\u0442\u043e\u0440\u044b \u043e\u0434\u043d\u043e\u0433\u043e \u0441\u043b\u043e\u0432\u0430 \u0432 \u0440\u0430\u0437\u043d\u044b\u0445 \u0444\u043e\u0440\u043c\u0430\u0445 (\u0431\u0435\u0433, \u0431\u0435\u0433\u0443, \u0431\u0435\u0433\u0430\u043b) \u043d\u0435 \u0437\u0430\u0441\u0447\u0438\u0442\u044b\u0432\u0430\u044e\u0442\u0441\u044f, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u0441\u0443\u0442\u044c \u0432 \u0442\u043e\u043c, \u0447\u0442\u043e\u0431\u044b \u0438\u0441\u043a\u0430\u0442\u044c \u0441\u043b\u043e\u0432\u0430 \u043f\u043e \u0437\u0432\u0443\u0447\u0430\u043d\u0438\u044e \u0438 \u043f\u0440\u0438 \u044d\u0442\u043e\u043c \u043f\u043e\u043c\u043d\u0438\u0442\u044c, \u0447\u0442\u043e \u0432\u044b \u0443\u0436\u0435 \u043d\u0430\u0437\u044b\u0432\u0430\u043b\u0438.",benefit:"\u0412 \u043f\u0435\u0440\u0432\u0443\u044e \u043e\u0447\u0435\u0440\u0435\u0434\u044c \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442\u0441\u044f \u0443\u043f\u0440\u0430\u0432\u043b\u044f\u044e\u0449\u0438\u0439 \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044c \u043d\u0430\u0434 \u0440\u0435\u0447\u044c\u044e \u2014 \u0443\u043c\u0435\u043d\u0438\u0435 \u0437\u0430\u043f\u0443\u0441\u0442\u0438\u0442\u044c \u043f\u043e\u0438\u0441\u043a \u043f\u043e \u043a\u043e\u043c\u0430\u043d\u0434\u0435, \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0430\u0442\u044c\u0441\u044f \u043c\u0435\u0436\u0434\u0443 \u0433\u0440\u0443\u043f\u043f\u0430\u043c\u0438 \u0441\u043b\u043e\u0432, \u043a\u043e\u0433\u0434\u0430 \u043e\u0434\u043d\u0430 \u0436\u0438\u043b\u0430 \u0438\u0441\u0441\u044f\u043a\u043b\u0430, \u0431\u044b\u0441\u0442\u0440\u043e \u0434\u043e\u0441\u0442\u0430\u0432\u0430\u0442\u044c \u0441\u043b\u043e\u0432\u0430 \u0438\u0437 \u043f\u0430\u043c\u044f\u0442\u0438 \u0438 \u043f\u043e\u0434\u0430\u0432\u043b\u044f\u0442\u044c \u043f\u043e\u0432\u0442\u043e\u0440\u044b \u0438 \u0437\u0430\u043f\u0440\u0435\u0449\u0451\u043d\u043d\u044b\u0435 \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u044b. \u041d\u0430\u0433\u0440\u0443\u0437\u043a\u0430 \u043b\u043e\u0436\u0438\u0442\u0441\u044f \u0431\u043e\u043b\u044c\u0448\u0435 \u043d\u0430 \u043b\u043e\u0431\u043d\u0443\u044e \u0441\u0430\u043c\u043e\u043e\u0440\u0433\u0430\u043d\u0438\u0437\u0430\u0446\u0438\u044e, \u0447\u0435\u043c \u043d\u0430 \u043e\u0431\u044a\u0451\u043c \u0441\u043b\u043e\u0432\u0430\u0440\u044f, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u0440\u0430\u0431\u043e\u0442\u0430\u044e\u0442 \u0433\u0438\u0431\u043a\u043e\u0441\u0442\u044c \u043c\u044b\u0448\u043b\u0435\u043d\u0438\u044f \u0438 \u0441\u0430\u043c\u043e\u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044c, \u0430 \u043d\u0435 \u043f\u0440\u043e\u0441\u0442\u043e \xab\u0437\u043d\u0430\u044e \u043c\u043d\u043e\u0433\u043e \u0441\u043b\u043e\u0432\xbb.",history:"\u0411\u0443\u043a\u0432\u0435\u043d\u043d\u0430\u044f \u0431\u0435\u0433\u043b\u043e\u0441\u0442\u044c \u0432\u043e\u0441\u0445\u043e\u0434\u0438\u0442 \u043a \u043f\u0438\u0441\u044c\u043c\u0435\u043d\u043d\u043e\u043c\u0443 \u0442\u0435\u0441\u0442\u0443 \u0441\u043b\u043e\u0432\u0435\u0441\u043d\u043e\u0439 \u0431\u0435\u0433\u043b\u043e\u0441\u0442\u0438 \u041b\u0443\u0438\u0441\u0430 \u0422\u0451\u0440\u0441\u0442\u043e\u0443\u043d\u0430 (1938), \u0447\u0430\u0441\u0442\u0438 \u0435\u0433\u043e \u0440\u0430\u0431\u043e\u0442\u044b \u043e \u043f\u0435\u0440\u0432\u0438\u0447\u043d\u044b\u0445 \u0443\u043c\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0445 \u0441\u043f\u043e\u0441\u043e\u0431\u043d\u043e\u0441\u0442\u044f\u0445. \u0423\u0441\u0442\u043d\u0443\u044e \u043a\u043b\u0438\u043d\u0438\u0447\u0435\u0441\u043a\u0443\u044e \u0432\u0435\u0440\u0441\u0438\u044e, \u043a\u043e\u0442\u043e\u0440\u0443\u044e \u043e\u0431\u044b\u0447\u043d\u043e \u0438 \u0438\u043c\u0435\u044e\u0442 \u0432 \u0432\u0438\u0434\u0443, \u0441\u0442\u0430\u043d\u0434\u0430\u0440\u0442\u0438\u0437\u0438\u0440\u043e\u0432\u0430\u043b\u0438 \u0410\u0440\u0442\u0443\u0440 \u0411\u0435\u043d\u0442\u043e\u043d \u0438 \u041a\u0435\u0440\u0440\u0438 \u0425\u044d\u043c\u0448\u0435\u0440 \u0432 1976 \u0433\u043e\u0434\u0443 \u043f\u043e\u0434 \u043d\u0430\u0437\u0432\u0430\u043d\u0438\u0435\u043c Controlled Oral Word Association Test, \u0441 \u0438\u0437\u0432\u0435\u0441\u0442\u043d\u044b\u043c\u0438 \u043d\u0430\u0431\u043e\u0440\u0430\u043c\u0438 \u0431\u0443\u043a\u0432 FAS \u0438 CFL. \u0422\u0435\u0441\u0442 \u0431\u044b\u0441\u0442\u0440\u043e \u0440\u0430\u0437\u043e\u0448\u0451\u043b\u0441\u044f \u043f\u043e \u043d\u0435\u0439\u0440\u043e\u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u0438 \u043a\u0430\u043a \u043a\u043e\u0440\u043e\u0442\u043a\u0430\u044f \u0438 \u0447\u0443\u0432\u0441\u0442\u0432\u0438\u0442\u0435\u043b\u044c\u043d\u0430\u044f \u043f\u0440\u043e\u0431\u0430 \u043b\u043e\u0431\u043d\u044b\u0445 \u0438 \u0440\u0435\u0447\u0435\u0432\u044b\u0445 \u0444\u0443\u043d\u043a\u0446\u0438\u0439 \u0438 \u0434\u043e \u0441\u0438\u0445 \u043f\u043e\u0440 \u043e\u0441\u0442\u0430\u0451\u0442\u0441\u044f \u043e\u0434\u043d\u0438\u043c \u0438\u0437 \u0441\u0430\u043c\u044b\u0445 \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0435\u043c\u044b\u0445.",creator:"\u0410\u0440\u0442\u0443\u0440 \u041b. \u0411\u0435\u043d\u0442\u043e\u043d \u0438 \u041a\u0435\u0440\u0440\u0438 \u0434\u0435\u0421. \u0425\u044d\u043c\u0448\u0435\u0440, \u043e\u0444\u043e\u0440\u043c\u0438\u0432\u0448\u0438\u0435 Controlled Oral Word Association Test (COWAT) \u0432 \u0441\u043e\u0441\u0442\u0430\u0432\u0435 Multilingual Aphasia Examination \u0432 1976 \u0433\u043e\u0434\u0443. \u0421\u0430\u043c\u0430 \u0438\u0434\u0435\u044f \u0441\u0442\u0430\u0440\u0448\u0435: \u043f\u0438\u0441\u044c\u043c\u0435\u043d\u043d\u044b\u0439 \u0432\u0430\u0440\u0438\u0430\u043d\u0442 \u0442\u0435\u0441\u0442\u0430 \u0441\u043e\u0437\u0434\u0430\u043b \u041b\u0443\u0438\u0441 \u0422\u0451\u0440\u0441\u0442\u043e\u0443\u043d \u0432 1938 \u0433\u043e\u0434\u0443, \u0442\u0430\u043a \u0447\u0442\u043e COWAT \u043f\u0440\u0430\u0432\u0438\u043b\u044c\u043d\u0435\u0435 \u0441\u0447\u0438\u0442\u0430\u0442\u044c \u0441\u0442\u0430\u043d\u0434\u0430\u0440\u0442\u0438\u0437\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u044b\u043c \u043a\u043b\u0438\u043d\u0438\u0447\u0435\u0441\u043a\u0438\u043c \u043d\u0430\u0441\u043b\u0435\u0434\u043d\u0438\u043a\u043e\u043c \u0435\u0433\u043e \u0440\u0430\u0431\u043e\u0442\u044b, \u0430 \u043d\u0435 \u0438\u0437\u043e\u0431\u0440\u0435\u0442\u0435\u043d\u0438\u0435\u043c \u0441 \u043d\u0443\u043b\u044f.",methods:"\u0421\u0438\u043b\u044c\u043d\u044b\u0439 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442 \u0434\u0435\u0440\u0436\u0438\u0442\u0441\u044f \u043d\u0430 \u0434\u0432\u0443\u0445 \u043f\u0440\u0438\u0451\u043c\u0430\u0445: \u043a\u043b\u0430\u0441\u0442\u0435\u0440\u0438\u0437\u0430\u0446\u0438\u044f (\u0440\u0430\u0437\u0440\u0430\u0431\u0430\u0442\u044b\u0432\u0430\u0442\u044c \u043e\u0434\u043d\u0443 \u0437\u0432\u0443\u043a\u043e\u0432\u0443\u044e \u0438\u043b\u0438 \u0441\u043c\u044b\u0441\u043b\u043e\u0432\u0443\u044e \u0433\u0440\u0443\u043f\u043f\u0443 \u2014 \u0434\u043b\u044f \xab\u041f\xbb: \xab\u043f\u0430\u0440\u043a, \u043f\u0435\u0447\u044c, \u043f\u0435\u043d\u044c\xbb, \u0437\u0430\u0442\u0435\u043c \xab\u043f\u043e\u0433\u043e\u0434\u0430, \u043f\u043e\u043b\u0435\xbb) \u0438 \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0435\u043d\u0438\u0435 (\u043f\u0440\u044b\u0433\u0430\u0442\u044c \u043a \u043d\u043e\u0432\u043e\u0439 \u0433\u0440\u0443\u043f\u043f\u0435, \u043a\u0430\u043a \u0442\u043e\u043b\u044c\u043a\u043e \u043f\u043e\u0442\u043e\u043a \u0441\u043b\u043e\u0432 \u0437\u0430\u043c\u0435\u0434\u043b\u0438\u043b\u0441\u044f). \u0418\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0439\u0442\u0435 \u043f\u0440\u0438\u0441\u0442\u0430\u0432\u043a\u0438 \u0438 \u0440\u0438\u0444\u043c\u0443\u044e\u0449\u0438\u0435\u0441\u044f \u0440\u044f\u0434\u044b \u043a\u0430\u043a \u0442\u0440\u0430\u043c\u043f\u043b\u0438\u043d\u044b, \u043f\u0440\u043e\u0445\u043e\u0434\u0438\u0442\u0435 \u0447\u0430\u0441\u0442\u044b\u0435 \u0441\u043e\u0447\u0435\u0442\u0430\u043d\u0438\u044f \u0441\u043e\u0433\u043b\u0430\u0441\u043d\u044b\u0445 (\u043f\u0440-, \u043f\u043b-, \u0441\u0442-), \u0438 \u043d\u0435 \u0437\u0430\u0432\u0438\u0441\u0430\u0439\u0442\u0435 \u043d\u0430 \u043a\u0430\u0447\u0435\u0441\u0442\u0432\u0435 \u2014 \u0432\u0430\u0436\u043d\u043e \u043a\u043e\u043b\u0438\u0447\u0435\u0441\u0442\u0432\u043e, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u0432\u044b\u043f\u0430\u043b\u0438\u0432\u0430\u0439\u0442\u0435 \u0438 \u0438\u0434\u0438\u0442\u0435 \u0434\u0430\u043b\u044c\u0448\u0435. \u041e\u0442\u043c\u0435\u0447\u0430\u0439\u0442\u0435 \u0441\u0432\u043e\u0438 \u0441\u043b\u0430\u0431\u044b\u0435 \u0431\u0443\u043a\u0432\u044b \u0438 \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0439\u0442\u0435 \u0438\u043c\u0435\u043d\u043d\u043e \u0438\u0445.",duration:"\u041e\u0434\u0438\u043d \u0440\u0430\u0443\u043d\u0434 \u0434\u043b\u0438\u0442\u0441\u044f 60 \u0441\u0435\u043a\u0443\u043d\u0434, \u0442\u0430\u043a \u0447\u0442\u043e \u0435\u0433\u043e \u043b\u0435\u0433\u043a\u043e \u0432\u0442\u0438\u0441\u043d\u0443\u0442\u044c \u043a\u0443\u0434\u0430 \u0443\u0433\u043e\u0434\u043d\u043e. \u041f\u043e\u043b\u0435\u0437\u043d\u044b\u0439 \u0437\u0430\u0445\u043e\u0434 \u2014 5\u201310 \u0431\u0443\u043a\u0432 \u0441 \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u043c\u0438 \u043f\u0430\u0443\u0437\u0430\u043c\u0438, \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0440\u0430\u0437 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e; \u0441\u0432\u043e\u0438 \u0446\u0438\u0444\u0440\u044b \u0432\u044b \u0443\u0432\u0438\u0434\u0438\u0442\u0435 \u0440\u0430\u0441\u0442\u0443\u0449\u0438\u043c\u0438 \u0434\u043e\u0432\u043e\u043b\u044c\u043d\u043e \u0431\u044b\u0441\u0442\u0440\u043e. \u041a\u0430\u043a \u0438 \u0432 \u0431\u043e\u043b\u044c\u0448\u0438\u043d\u0441\u0442\u0432\u0435 \u043f\u043e\u0434\u043e\u0431\u043d\u044b\u0445 \u0437\u0430\u0434\u0430\u0447, \u043e\u0442\u0434\u0430\u0447\u0430 \u0432\u044b\u0445\u043e\u0434\u0438\u0442 \u043d\u0430 \u043f\u043b\u0430\u0442\u043e \u0447\u0435\u0440\u0435\u0437 \u043f\u0430\u0440\u0443 \u043d\u0435\u0434\u0435\u043b\u044c, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u043b\u0443\u0447\u0448\u0435 \u043c\u0435\u043d\u044f\u0442\u044c \u0431\u0443\u043a\u0432\u044b \u0438 \u0434\u043e\u0431\u0430\u0432\u043b\u044f\u0442\u044c \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u044b \u043d\u0438\u0436\u0435, \u0447\u0435\u043c \u0434\u043e\u043b\u0431\u0438\u0442\u044c \u043e\u0434\u0438\u043d \u0438 \u0442\u043e\u0442 \u0436\u0435 \u0441\u0442\u0438\u043c\u0443\u043b.",research:"\u0422\u0432\u0451\u0440\u0434\u043e \u0443\u0441\u0442\u0430\u043d\u043e\u0432\u043b\u0435\u043d\u043e, \u0447\u0442\u043e COWAT \u2014 \u043d\u0430\u0434\u0451\u0436\u043d\u0430\u044f \u0438 \u0445\u043e\u0440\u043e\u0448\u043e \u043f\u0440\u043e\u0432\u0435\u0440\u0435\u043d\u043d\u0430\u044f \u043a\u043b\u0438\u043d\u0438\u0447\u0435\u0441\u043a\u0430\u044f \u043c\u0435\u0442\u043e\u0434\u0438\u043a\u0430, \u0438 \u0447\u0442\u043e \u0441 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u043e\u0439 \u0432\u044b \u0437\u0430\u043c\u0435\u0442\u043d\u043e \u043f\u0440\u0438\u0431\u0430\u0432\u043b\u044f\u0435\u0442\u0435 \u0432 \u0441\u0430\u043c\u043e\u0439 \u0431\u0435\u0433\u043b\u043e\u0441\u0442\u0438. \u0427\u0435\u0441\u0442\u043d\u0430\u044f \u043e\u0433\u043e\u0432\u043e\u0440\u043a\u0430 \u2014 \u043f\u0440\u043e \u043f\u0435\u0440\u0435\u043d\u043e\u0441: \u043e\u0431\u0437\u043e\u0440\u044b \u0442\u0440\u0435\u043d\u0430\u0436\u0451\u0440\u043e\u0432 \u0434\u043b\u044f \u043c\u043e\u0437\u0433\u0430 (\u043d\u0430\u043f\u0440\u0438\u043c\u0435\u0440, \u0421\u0430\u0439\u043c\u043e\u043d\u0441 \u0441 \u043a\u043e\u043b\u043b\u0435\u0433\u0430\u043c\u0438, 2016, \u0438 \u043c\u0435\u0442\u0430\u0430\u043d\u0430\u043b\u0438\u0437\u044b \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0438 \u0440\u0430\u0431\u043e\u0447\u0435\u0439 \u043f\u0430\u043c\u044f\u0442\u0438) \u043f\u043e\u043a\u0430\u0437\u044b\u0432\u0430\u044e\u0442, \u0447\u0442\u043e \u043f\u0440\u0438\u0440\u043e\u0441\u0442 \u043d\u0430 \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u043c\u043e\u0439 \u0437\u0430\u0434\u0430\u0447\u0435 \u0440\u0435\u0434\u043a\u043e \u043f\u0435\u0440\u0435\u0445\u043e\u0434\u0438\u0442 \u043d\u0430 \u043e\u0431\u0449\u0438\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442, \u043f\u043e\u0432\u0441\u0435\u0434\u043d\u0435\u0432\u043d\u043e\u0435 \u043c\u044b\u0448\u043b\u0435\u043d\u0438\u0435 \u0438\u043b\u0438 \u0437\u0430\u0449\u0438\u0442\u0443 \u043e\u0442 \u0432\u043e\u0437\u0440\u0430\u0441\u0442\u043d\u043e\u0433\u043e \u0441\u043f\u0430\u0434\u0430. \u041a \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f\u043c \xab\u043f\u043e\u0434\u043d\u0438\u043c\u0435\u0442 IQ\xbb \u0438\u043b\u0438 \xab\u0437\u0430\u0449\u0438\u0442\u0438\u0442 \u043e\u0442 \u0434\u0435\u043c\u0435\u043d\u0446\u0438\u0438\xbb \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u0435\u0441\u044c \u043a\u0430\u043a \u043a \u043d\u0435\u0434\u043e\u043a\u0430\u0437\u0430\u043d\u043d\u044b\u043c \u2014 \u043d\u0430\u0434\u0451\u0436\u043d\u0430\u044f \u043f\u043e\u043b\u044c\u0437\u0430 \u0432 \u0442\u043e\u043c, \u0447\u0442\u043e \u043f\u043e\u0438\u0441\u043a \u0441\u043b\u043e\u0432 \u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u0441\u044f \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u0438 \u0433\u0438\u0431\u0447\u0435.",rec:"\u0411\u0435\u0440\u0438\u0442\u0435 \u0442\u0440\u0438 \u0431\u0443\u043a\u0432\u044b \u0432 \u0434\u0435\u043d\u044c, \u043f\u043e 60 \u0441\u0435\u043a\u0443\u043d\u0434 \u043d\u0430 \u043a\u0430\u0436\u0434\u0443\u044e, \u0438 \u043d\u0435\u0433\u0440\u043e\u043c\u043a\u043e \u0441\u0447\u0438\u0442\u0430\u0439\u0442\u0435 \u0432\u0441\u043b\u0443\u0445 \u2014 \u043f\u0440\u043e\u0433\u043e\u0432\u0430\u0440\u0438\u0432\u0430\u043d\u0438\u0435 \u0441\u043b\u043e\u0432 \u0437\u0430\u0434\u0430\u0451\u0442 \u0442\u043e\u0442 \u0441\u0430\u043c\u044b\u0439 \u0440\u0438\u0442\u043c \xab\u0434\u043e\u0441\u0442\u0430\u043b \u0438 \u043f\u043e\u0448\u0451\u043b \u0434\u0430\u043b\u044c\u0448\u0435\xbb, \u0440\u0430\u0434\u0438 \u043a\u043e\u0442\u043e\u0440\u043e\u0433\u043e \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u0435 \u0438 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442.",faq:[["\u0427\u0435\u043c \u044d\u0442\u043e \u043e\u0442\u043b\u0438\u0447\u0430\u0435\u0442\u0441\u044f \u043e\u0442 \u043f\u0435\u0440\u0435\u0447\u0438\u0441\u043b\u0435\u043d\u0438\u044f \u0436\u0438\u0432\u043e\u0442\u043d\u044b\u0445 \u0438\u043b\u0438 \u0434\u0440\u0443\u0433\u0438\u0445 \u043a\u0430\u0442\u0435\u0433\u043e\u0440\u0438\u0439?","\u0411\u0443\u043a\u0432\u0435\u043d\u043d\u0430\u044f (\u0444\u043e\u043d\u0435\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u0430\u044f) \u0431\u0435\u0433\u043b\u043e\u0441\u0442\u044c \u0437\u0430\u0441\u0442\u0430\u0432\u043b\u044f\u0435\u0442 \u0438\u0441\u043a\u0430\u0442\u044c \u0441\u043b\u043e\u0432\u043e \u043f\u043e \u0437\u0432\u0443\u0447\u0430\u043d\u0438\u044e, \u0430 \u044d\u0442\u043e \u0442\u0440\u0435\u0431\u0443\u0435\u0442 \u0431\u043e\u043b\u0435\u0435 \u043e\u0441\u043e\u0437\u043d\u0430\u043d\u043d\u043e\u0433\u043e \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0435\u043d\u0438\u044f \u0438 \u043d\u0430\u0433\u0440\u0443\u0436\u0430\u0435\u0442 \u043b\u043e\u0431\u043d\u044b\u0439 \u0443\u043f\u0440\u0430\u0432\u043b\u044f\u044e\u0449\u0438\u0439 \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044c; \u043a\u0430\u0442\u0435\u0433\u043e\u0440\u0438\u0430\u043b\u044c\u043d\u0430\u044f (\u0441\u0435\u043c\u0430\u043d\u0442\u0438\u0447\u0435\u0441\u043a\u0430\u044f) \u0431\u0435\u0433\u043b\u043e\u0441\u0442\u044c \u043f\u043e\u0437\u0432\u043e\u043b\u044f\u0435\u0442 \u0438\u0434\u0442\u0438 \u043f\u043e \u0430\u0441\u0441\u043e\u0446\u0438\u0430\u0446\u0438\u044f\u043c \u0432\u043d\u0443\u0442\u0440\u0438 \u0442\u0435\u043c\u044b \u0438 \u0431\u043e\u043b\u044c\u0448\u0435 \u043e\u043f\u0438\u0440\u0430\u0435\u0442\u0441\u044f \u043d\u0430 \u0441\u043b\u043e\u0432\u0430\u0440\u043d\u044b\u0435 \u0437\u043d\u0430\u043d\u0438\u044f \u0432\u0438\u0441\u043e\u0447\u043d\u043e\u0439 \u0434\u043e\u043b\u0438. \u041f\u043e \u043a\u0430\u0442\u0435\u0433\u043e\u0440\u0438\u044f\u043c \u0431\u043e\u043b\u044c\u0448\u0438\u043d\u0441\u0442\u0432\u043e \u043d\u0430\u0431\u0438\u0440\u0430\u0435\u0442 \u0447\u0443\u0442\u044c \u0431\u043e\u043b\u044c\u0448\u0435."],["\u0421\u0442\u0430\u043d\u0435\u0442 \u043b\u0438 \u043e\u0442 \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043e\u043a \u0443\u043c\u043d\u0435\u0435 \u0438\u043b\u0438 \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u0432 \u0440\u0430\u0437\u0433\u043e\u0432\u043e\u0440\u0435?","\u0412 \u0441\u0430\u043c\u043e\u0439 \u0437\u0430\u0434\u0430\u0447\u0435 \u043d\u0430 \u0431\u0435\u0433\u043b\u043e\u0441\u0442\u044c \u0432\u044b \u043d\u0430\u0434\u0451\u0436\u043d\u043e \u043f\u0440\u0438\u0431\u0430\u0432\u0438\u0442\u0435 \u0438, \u0432\u043e\u0437\u043c\u043e\u0436\u043d\u043e, \u0431\u0443\u0434\u0435\u0442\u0435 \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u0434\u043e\u0441\u0442\u0430\u0432\u0430\u0442\u044c \u0441\u043b\u043e\u0432\u0430. \u041d\u043e \u0448\u0438\u0440\u043e\u043a\u0438\u0439 \u043f\u0435\u0440\u0435\u043d\u043e\u0441 \u043d\u0430 \u043e\u0431\u0449\u0438\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0438\u043b\u0438 \u043f\u043e\u0432\u0441\u0435\u0434\u043d\u0435\u0432\u043d\u0443\u044e \u0440\u0435\u0447\u044c \u0432 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u044f\u0445 \u0441\u043b\u0430\u0431\u044b\u0439 \u0438 \u0441\u043f\u043e\u0440\u043d\u044b\u0439, \u0442\u0430\u043a \u0447\u0442\u043e \u0441\u0447\u0438\u0442\u0430\u0439\u0442\u0435 \u044d\u0442\u043e \u0442\u043e\u0447\u0435\u0447\u043d\u043e\u0439 \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u043e\u0439 \u043f\u043e\u0434\u0431\u043e\u0440\u0430 \u0441\u043b\u043e\u0432, \u0430 \u043d\u0435 \u0441\u043f\u043e\u0441\u043e\u0431\u043e\u043c \u043f\u043e\u0434\u043d\u044f\u0442\u044c IQ."],["\u041a\u0430\u043a\u043e\u0439 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442 \u0441\u0447\u0438\u0442\u0430\u0435\u0442\u0441\u044f \u0445\u043e\u0440\u043e\u0448\u0438\u043c?","\u0415\u0434\u0438\u043d\u043e\u0439 \u0446\u0438\u0444\u0440\u044b \u043d\u0435\u0442 \u2014 \u0438\u0442\u043e\u0433 \u0441\u0438\u043b\u044c\u043d\u043e \u0437\u0430\u0432\u0438\u0441\u0438\u0442 \u043e\u0442 \u0432\u043e\u0437\u0440\u0430\u0441\u0442\u0430, \u043e\u0431\u0440\u0430\u0437\u043e\u0432\u0430\u043d\u0438\u044f \u0438 \u044f\u0437\u044b\u043a\u0430. \u041a\u0430\u043a \u0433\u0440\u0443\u0431\u044b\u0439 \u043e\u0440\u0438\u0435\u043d\u0442\u0438\u0440, \u0437\u0434\u043e\u0440\u043e\u0432\u044b\u0435 \u0432\u0437\u0440\u043e\u0441\u043b\u044b\u0435 \u0447\u0430\u0441\u0442\u043e \u043d\u0430\u0437\u044b\u0432\u0430\u044e\u0442 \u043f\u043e\u0440\u044f\u0434\u043a\u0430 \u043f\u043e\u043b\u0443\u0442\u043e\u0440\u0430 \u0434\u0435\u0441\u044f\u0442\u043a\u043e\u0432 \u0441\u043b\u043e\u0432 \u043d\u0430 \u0431\u0443\u043a\u0432\u0443 \u0437\u0430 60 \u0441\u0435\u043a\u0443\u043d\u0434, \u043d\u043e \u043e\u0441\u043c\u044b\u0441\u043b\u0435\u043d\u043d\u0435\u0435 \u0441\u0440\u0430\u0432\u043d\u0438\u0432\u0430\u0442\u044c \u0441\u0435\u0431\u044f \u0441\u043e \u0441\u0432\u043e\u0438\u043c\u0438 \u043f\u0440\u0435\u0436\u043d\u0438\u043c\u0438 \u0440\u0430\u0443\u043d\u0434\u0430\u043c\u0438, \u0430 \u043d\u0435 \u0441 \u0444\u0438\u043a\u0441\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u043e\u0439 \u043f\u043b\u0430\u043d\u043a\u043e\u0439."]],variants:"\u0421\u0435\u043c\u0430\u043d\u0442\u0438\u0447\u0435\u0441\u043a\u0430\u044f (\u043a\u0430\u0442\u0435\u0433\u043e\u0440\u0438\u0430\u043b\u044c\u043d\u0430\u044f) \u0431\u0435\u0433\u043b\u043e\u0441\u0442\u044c \u2014 \u043d\u0430\u0437\u044b\u0432\u0430\u0442\u044c \u0436\u0438\u0432\u043e\u0442\u043d\u044b\u0445, \u0444\u0440\u0443\u043a\u0442\u044b \u0438\u043b\u0438 \u043f\u0440\u043e\u0444\u0435\u0441\u0441\u0438\u0438 \u0432\u043c\u0435\u0441\u0442\u043e \u0431\u0443\u043a\u0432\u044b; \u043e\u043d\u0430 \u043e\u043f\u0438\u0440\u0430\u0435\u0442\u0441\u044f \u0431\u043e\u043b\u044c\u0448\u0435 \u043d\u0430 \u0441\u043b\u043e\u0432\u0430\u0440\u043d\u044b\u0435 \u0437\u0430\u043f\u0430\u0441\u044b \u0432\u0438\u0441\u043e\u0447\u043d\u043e\u0439 \u0434\u043e\u043b\u0438, \u0447\u0435\u043c \u043d\u0430 \u043b\u043e\u0431\u043d\u043e\u0435 \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0435\u043d\u0438\u0435. \u0414\u0440\u0443\u0433\u0438\u0435 \u0432\u0435\u0440\u0441\u0438\u0438: \u0431\u0435\u0433\u043b\u043e\u0441\u0442\u044c \u0441 \u0437\u0430\u043f\u0440\u0435\u0442\u043d\u043e\u0439 \u0431\u0443\u043a\u0432\u043e\u0439 (\u0441\u043b\u043e\u0432\u0430, \u0432 \u043a\u043e\u0442\u043e\u0440\u044b\u0445 \u0435\u0451 \u041d\u0415\u0422), \u0431\u0435\u0433\u043b\u043e\u0441\u0442\u044c \u043d\u0430 \u0433\u043b\u0430\u0433\u043e\u043b\u044b, \u043e\u0433\u0440\u0430\u043d\u0438\u0447\u0435\u043d\u0438\u0435 \u043f\u043e \u0434\u0432\u0443\u043c \u0431\u0443\u043a\u0432\u0430\u043c, \u0430 \u0442\u0430\u043a\u0436\u0435 \u0437\u0430\u0434\u0430\u0447\u0438 \u043d\u0430 \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0435\u043d\u0438\u0435, \u0433\u0434\u0435 \u043a\u0430\u0436\u0434\u044b\u0435 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0441\u043b\u043e\u0432 \u0447\u0435\u0440\u0435\u0434\u0443\u044e\u0442\u0441\u044f \u0431\u0443\u043a\u0432\u0430 \u0438 \u043a\u0430\u0442\u0435\u0433\u043e\u0440\u0438\u044f."},en:{about:"Phonemic Fluency is a timed word-generation exercise: you are given a single letter and must say or type as many words starting with it as you can within a fixed window, usually 60 seconds. Proper names, numbers and repeated forms of the same word (run, running, ran) don't count, so the real game is searching your vocabulary by sound while keeping track of what you've already used.",benefit:"It mainly trains executive control over language \u2014 the ability to start a search on demand, switch between word groups when a vein runs dry, retrieve quickly, and inhibit repeats and forbidden answers. It leans more on frontal-lobe self-organisation than on raw vocabulary size, which is why it stresses mental flexibility and self-monitoring rather than just 'knowing more words'.",history:"Letter-based word fluency goes back to Louis Thurstone's written Word Fluency Test (1938), part of his Primary Mental Abilities work. The oral clinical version most people mean today was standardised by Arthur Benton and Kerry Hamsher in 1976 as the Controlled Oral Word Association Test, using the now-famous FAS and CFL letter sets. It spread quickly through neuropsychology as a quick, sensitive probe of frontal and language function and is still one of the most widely administered tests in the field.",creator:"Arthur L. Benton and Kerry deS. Hamsher, who formalised the Controlled Oral Word Association Test (COWAT) within the Multilingual Aphasia Examination in 1976. The underlying idea is older: the written word-fluency task was created by Louis Thurstone in 1938, so the COWAT is best described as the standardised clinical descendant of Thurstone's work rather than an invention from scratch.",methods:"Two strategies dominate strong performance: clustering (mining one phonetic or semantic pocket at a time \u2014 for F: 'fast, far, fall, fail' then 'fish, fin') and switching (jumping to a fresh pocket the moment output slows). Use prefixes and rhyme families as launch pads, sweep through common consonant blends (fl-, fr-, sp-, st-), and don't freeze on quality \u2014 quantity wins, so blurt and move on. Note your weak letters and drill those.",duration:"Single rounds are 60 seconds, so it fits anywhere. A useful session is 5\u201310 letters with short breaks, a few times a week; you will see your own counts climb fairly quickly. Like most such tasks, returns flatten after a few weeks, so rotate letters and add the variants below to stay challenged rather than grinding the same prompt.",research:"What's solidly established is that the COWAT is a reliable, well-validated clinical measure, and that with practice you get clearly better at fluency itself. The honest caveat is transfer: brain-training reviews (such as Simons and colleagues, 2016, and meta-analyses of working-memory training) find that gains on trained tasks rarely spread to general intelligence, everyday thinking, or protection against age-related decline. Treat 'raises IQ' or 'prevents dementia' claims as unproven \u2014 the dependable benefit is a faster, more flexible word search.",rec:"Pick three letters a day, hit 60 seconds each, and quietly count out loud \u2014 speaking the words forces the retrieve-and-move-on rhythm that the exercise is really about.",faq:[["How is this different from naming animals or other categories?","Letter (phonemic) fluency makes you search by how a word sounds, which forces more deliberate strategy switching and leans on frontal executive control; category (semantic) fluency lets you ride associations within a topic and draws more on temporal-lobe word knowledge. Most people score a bit higher on categories."],["Will training this make me smarter or quicker in conversation?","You'll reliably get better at the fluency task itself and may feel faster at pulling words. But broad carry-over to general intelligence or everyday speech is weak and contested in the research, so treat it as targeted practice for word retrieval, not an IQ booster."],["What's a good score?","There's no single number \u2014 results depend heavily on age, education and language. As a rough adult reference, healthy speakers often produce somewhere in the mid-teens of words per letter in 60 seconds, but the most meaningful comparison is against your own earlier rounds, not a fixed target."]],variants:"Semantic (category) fluency \u2014 name animals, fruits or jobs instead of a letter; it leans more on temporal-lobe word stores than on frontal switching. Other twists: excluded-letter fluency (words that must NOT contain a given letter), action fluency (verbs only), two-letter constraints, and switching tasks that alternate between a letter and a category every few words."},es:{about:"La Fluidez Fon\xe9mica es un ejercicio cronometrado de generaci\xf3n de palabras: se te da una sola letra y debes decir o escribir tantas palabras que empiecen por ella como puedas dentro de una ventana fija, normalmente 60 segundos. Los nombres propios, los n\xfameros y las formas repetidas de una misma palabra (corro, corriendo, corr\xed) no cuentan, as\xed que el verdadero juego consiste en rastrear tu vocabulario por el sonido mientras llevas la cuenta de lo que ya has usado.",benefit:"Entrena sobre todo el control ejecutivo del lenguaje: la capacidad de iniciar una b\xfasqueda a demanda, cambiar de grupo de palabras cuando se agota un fil\xf3n, recuperar deprisa e inhibir las repeticiones y las respuestas prohibidas. Se apoya m\xe1s en la autoorganizaci\xf3n del l\xf3bulo frontal que en el tama\xf1o bruto del vocabulario, por eso pone a prueba la flexibilidad mental y la autosupervisi\xf3n m\xe1s que el simple 'saber m\xe1s palabras'.",history:"La fluidez verbal basada en letras se remonta al Test de Fluidez de Palabras escrito de Louis Thurstone (1938), parte de su trabajo sobre las Aptitudes Mentales Primarias. La versi\xf3n cl\xednica oral que la mayor\xeda tiene hoy en mente la estandarizaron Arthur Benton y Kerry Hamsher en 1976 como el Test Controlado de Asociaci\xf3n Oral de Palabras, usando los ya famosos conjuntos de letras FAS y CFL. Se extendi\xf3 r\xe1pidamente por la neuropsicolog\xeda como una sonda breve y sensible de la funci\xf3n frontal y del lenguaje, y sigue siendo una de las pruebas m\xe1s administradas del campo.",creator:"Arthur L. Benton y Kerry deS. Hamsher, que formalizaron el Test Controlado de Asociaci\xf3n Oral de Palabras (COWAT) dentro del Examen Multiling\xfce de la Afasia en 1976. La idea de fondo es m\xe1s antigua: la tarea escrita de fluidez de palabras la cre\xf3 Louis Thurstone en 1938, as\xed que el COWAT se describe mejor como el descendiente cl\xednico estandarizado del trabajo de Thurstone que como una invenci\xf3n partida de cero.",methods:"Dos estrategias dominan el buen rendimiento: agrupar (explotar un bolsillo fon\xe9tico o sem\xe1ntico cada vez; para la F: 'f\xe1cil, faro, falda, falla' y luego 'foca, fila, fin') y cambiar (saltar a un bolsillo nuevo en cuanto la producci\xf3n se ralentiza). Usa prefijos y familias de rima como trampolines, recorre los grupos conson\xe1nticos comunes (fl-, fr-, pr-, tr-) y no te bloquees con la calidad: gana la cantidad, as\xed que su\xe9ltalo y sigue. Anota tus letras flojas y entr\xe9nalas.",duration:"Cada ronda dura 60 segundos, as\xed que cabe en cualquier hueco. Una sesi\xf3n \xfatil son 5\u201310 letras con descansos breves, algunas veces por semana; ver\xe1s subir tus propias cuentas bastante r\xe1pido. Como en casi todas estas tareas, los avances se aplanan tras unas semanas, as\xed que rota las letras y a\xf1ade las variantes de abajo para seguir teniendo reto en lugar de machacar el mismo est\xedmulo.",research:"Lo s\xf3lidamente establecido es que el COWAT es una medida cl\xednica fiable y bien validada, y que con la pr\xe1ctica mejoras claramente en la propia fluidez. La advertencia honesta es la transferencia: las revisiones sobre entrenamiento cerebral (como la de Simons y colaboradores, 2016, y los metaan\xe1lisis del entrenamiento de la memoria de trabajo) hallan que las mejoras en las tareas entrenadas rara vez se extienden a la inteligencia general, al pensamiento cotidiano o a la protecci\xf3n frente al deterioro asociado a la edad. Toma como no demostradas las afirmaciones de que 'sube el CI' o 'previene la demencia': el beneficio fiable es una b\xfasqueda de palabras m\xe1s r\xe1pida y flexible.",rec:"Elige tres letras al d\xeda, ded\xedcales 60 segundos cada una y cuenta en voz baja; pronunciar las palabras impone el ritmo de recuperar-y-seguir que es de lo que va de verdad el ejercicio.",faq:[["\xbfEn qu\xe9 se diferencia esto de nombrar animales u otras categor\xedas?","La fluidez por letra (fon\xe9mica) te hace buscar por c\xf3mo suena una palabra, lo que fuerza un cambio de estrategia m\xe1s deliberado y se apoya en el control ejecutivo frontal; la fluidez por categor\xeda (sem\xe1ntica) te deja seguir asociaciones dentro de un tema y recurre m\xe1s al conocimiento de palabras del l\xf3bulo temporal. La mayor\xeda punt\xfaa algo m\xe1s alto en las categor\xedas."],["\xbfEntrenar esto me har\xe1 m\xe1s listo o m\xe1s \xe1gil al conversar?","Mejorar\xe1s de forma fiable en la propia tarea de fluidez y puede que te sientas m\xe1s r\xe1pido al sacar palabras. Pero la transferencia amplia a la inteligencia general o al habla cotidiana es d\xe9bil y discutida en la investigaci\xf3n, as\xed que t\xf3malo como pr\xe1ctica dirigida para la recuperaci\xf3n de palabras, no como un potenciador del CI."],["\xbfCu\xe1l es una buena puntuaci\xf3n?","No hay una cifra \xfanica: los resultados dependen mucho de la edad, la educaci\xf3n y el idioma. Como referencia aproximada en adultos, los hablantes sanos suelen producir alrededor de quince palabras por letra en 60 segundos, pero la comparaci\xf3n m\xe1s significativa es contra tus propias rondas anteriores, no contra un objetivo fijo."]],variants:"Fluidez sem\xe1ntica (por categor\xedas): nombrar animales, frutas u oficios en lugar de una letra; se apoya m\xe1s en los almacenes de palabras del l\xf3bulo temporal que en el cambio frontal. Otros giros: fluidez con letra excluida (palabras que NO deben contener una letra dada), fluidez de acciones (solo verbos), restricciones de dos letras y tareas de cambio que alternan entre una letra y una categor\xeda cada pocas palabras."},de:{about:"Phonemische Wortfl\xfcssigkeit ist eine Wortgenerierungsaufgabe auf Zeit: Du bekommst einen einzelnen Buchstaben und musst innerhalb eines festen Fensters \u2013 meist 60 Sekunden \u2013 so viele W\xf6rter nennen oder tippen, die damit beginnen, wie du kannst. Eigennamen, Zahlen und wiederholte Formen desselben Wortes (laufen, lief, gelaufen) z\xe4hlen nicht, sodass das eigentliche Spiel darin besteht, deinen Wortschatz nach Klang zu durchsuchen und dabei im Auge zu behalten, was du schon verwendet hast.",benefit:"Trainiert wird vor allem die exekutive Kontrolle \xfcber Sprache \u2013 die F\xe4higkeit, eine Suche auf Kommando zu starten, zwischen Wortgruppen zu wechseln, wenn eine Ader versiegt, schnell abzurufen und Wiederholungen sowie verbotene Antworten zu unterdr\xfccken. Sie st\xfctzt sich mehr auf die Selbstorganisation des Frontallappens als auf die schiere Gr\xf6\xdfe des Wortschatzes, weshalb sie eher geistige Flexibilit\xe4t und Selbst\xfcberwachung beansprucht als blo\xdfes \u201emehr W\xf6rter kennen\u201c.",history:"Buchstabenbasierte Wortfl\xfcssigkeit geht auf Louis Thurstones schriftlichen Word Fluency Test (1938) zur\xfcck, Teil seiner Arbeit zu den Primary Mental Abilities. Die m\xfcndliche klinische Version, die heute die meisten meinen, wurde 1976 von Arthur Benton und Kerry Hamsher als Controlled Oral Word Association Test standardisiert, mit den heute ber\xfchmten Buchstabens\xe4tzen FAS und CFL. Sie verbreitete sich rasch durch die Neuropsychologie als schnelle, empfindliche Sonde der Frontal- und Sprachfunktion und ist nach wie vor einer der am h\xe4ufigsten durchgef\xfchrten Tests des Feldes.",creator:"Arthur L. Benton und Kerry deS. Hamsher, die den Controlled Oral Word Association Test (COWAT) 1976 innerhalb des Multilingual Aphasia Examination formalisierten. Die zugrunde liegende Idee ist \xe4lter: Die schriftliche Wortfl\xfcssigkeitsaufgabe wurde 1938 von Louis Thurstone geschaffen, sodass der COWAT am besten als standardisierter klinischer Nachfahre von Thurstones Arbeit beschrieben wird, nicht als Erfindung von Grund auf.",methods:"Zwei Strategien pr\xe4gen starke Leistung: das Clustern (eine phonetische oder semantische Nische nach der anderen aussch\xf6pfen \u2013 f\xfcr F: \u201efast, fern, fallen, fehlen\u201c, dann \u201eFisch, Fee, Feder\u201c) und das Wechseln (in eine frische Nische springen, sobald der Aussto\xdf nachl\xe4sst). Nutze Vorsilben und Reimfamilien als Sprungbretter, geh die h\xe4ufigen Konsonantenverbindungen durch (fl-, fr-, sp-, st-) und friere nicht \xfcber der Qualit\xe4t ein \u2013 Menge gewinnt, also raus damit und weiter. Notiere dir deine schwachen Buchstaben und \xfcbe genau die.",duration:"Einzelne Durchg\xe4nge dauern 60 Sekunden, passen also \xfcberallhin. Eine sinnvolle Sitzung sind 5\u201310 Buchstaben mit kurzen Pausen, ein paar Mal pro Woche; du wirst deine eigenen Zahlen recht schnell steigen sehen. Wie bei den meisten solchen Aufgaben flachen die Zuw\xe4chse nach ein paar Wochen ab, also wechsle die Buchstaben und erg\xe4nze die untenstehenden Varianten, um gefordert zu bleiben, statt dieselbe Vorgabe abzuarbeiten.",research:"Solide belegt ist, dass der COWAT ein zuverl\xe4ssiges, gut validiertes klinisches Ma\xdf ist und dass du mit \xdcbung klar besser in der Wortfl\xfcssigkeit selbst wirst. Der ehrliche Vorbehalt ist der Transfer: \xdcbersichtsarbeiten zum Gehirntraining (etwa Simons und Kollegen, 2016, sowie Meta-Analysen zum Arbeitsged\xe4chtnistraining) finden, dass sich Zuw\xe4chse bei trainierten Aufgaben selten auf die allgemeine Intelligenz, das allt\xe4gliche Denken oder den Schutz vor altersbedingtem Abbau ausbreiten. Behandle Behauptungen wie \u201esteigert den IQ\u201c oder \u201ebeugt Demenz vor\u201c als unbewiesen \u2013 der verl\xe4ssliche Nutzen ist eine schnellere, flexiblere Wortsuche.",rec:"W\xe4hle drei Buchstaben pro Tag, gib bei jedem 60 Sekunden alles und z\xe4hle leise laut mit \u2013 das Aussprechen der W\xf6rter erzwingt den Abrufen-und-weiter-Rhythmus, um den es bei der \xdcbung eigentlich geht.",faq:[["Wie unterscheidet sich das vom Aufz\xe4hlen von Tieren oder anderen Kategorien?","Buchstaben- (phonemische) Fl\xfcssigkeit l\xe4sst dich danach suchen, wie ein Wort klingt, was bewussteres Strategiewechseln erzwingt und sich auf die frontale exekutive Kontrolle st\xfctzt; Kategorie- (semantische) Fl\xfcssigkeit l\xe4sst dich Assoziationen innerhalb eines Themas folgen und zieht st\xe4rker auf das Wortwissen des Temporallappens. Die meisten schneiden bei Kategorien etwas besser ab."],["Macht mich das Training kl\xfcger oder schlagfertiger im Gespr\xe4ch?","Du wirst zuverl\xe4ssig besser in der Fl\xfcssigkeitsaufgabe selbst und f\xfchlst dich vielleicht schneller im W\xf6rter-Hervorholen. Aber ein breiter \xdcbertrag auf die allgemeine Intelligenz oder die allt\xe4gliche Sprache ist in der Forschung schwach und umstritten \u2013 behandle es als gezielte \xdcbung f\xfcr den Wortabruf, nicht als IQ-Booster."],["Was ist ein guter Wert?","Es gibt keine einzelne Zahl \u2013 die Ergebnisse h\xe4ngen stark von Alter, Bildung und Sprache ab. Als grober Richtwert f\xfcr Erwachsene bringen gesunde Sprecher pro Buchstabe oft irgendwo um die f\xfcnfzehn W\xf6rter in 60 Sekunden hervor, aber der aussagekr\xe4ftigste Vergleich ist der gegen deine eigenen fr\xfcheren Durchg\xe4nge, nicht gegen eine feste Vorgabe."]],variants:"Semantische (Kategorie-)Fl\xfcssigkeit \u2013 nenne Tiere, Fr\xfcchte oder Berufe statt eines Buchstabens; sie st\xfctzt sich mehr auf die Wortspeicher des Temporallappens als auf frontales Wechseln. Weitere Abwandlungen: Ausschluss-Buchstaben-Fl\xfcssigkeit (W\xf6rter, die einen bestimmten Buchstaben NICHT enthalten d\xfcrfen), Verb-Fl\xfcssigkeit (nur Verben), Zwei-Buchstaben-Vorgaben und Wechselaufgaben, die alle paar W\xf6rter zwischen einem Buchstaben und einer Kategorie hin- und herspringen."},pt:{about:"A Flu\xeancia Fon\xe9mica \xe9 um exerc\xedcio cronometrado de gera\xe7\xe3o de palavras: d\xe3o-lhe uma \xfanica letra e voc\xea deve dizer ou digitar o maior n\xfamero poss\xedvel de palavras come\xe7adas por ela dentro de uma janela fixa, em geral 60 segundos. Nomes pr\xf3prios, n\xfameros e formas repetidas da mesma palavra (correr, correndo, corri) n\xe3o contam, por isso o verdadeiro jogo \xe9 vasculhar o seu vocabul\xe1rio pelo som sem perder de vista o que voc\xea j\xe1 usou.",benefit:"Treina sobretudo o controle executivo sobre a linguagem \u2014 a capacidade de iniciar uma busca sob demanda, alternar entre grupos de palavras quando um veio se esgota, recuperar rapidamente e inibir repeti\xe7\xf5es e respostas proibidas. Apoia-se mais na auto-organiza\xe7\xe3o do lobo frontal do que no tamanho bruto do vocabul\xe1rio, e \xe9 por isso que enfatiza a flexibilidade mental e o automonitoramento, e n\xe3o apenas 'saber mais palavras'.",history:"A flu\xeancia de palavras baseada em letras remonta ao Word Fluency Test escrito de Louis Thurstone (1938), parte do seu trabalho sobre as Aptid\xf5es Mentais Prim\xe1rias. A vers\xe3o cl\xednica oral que a maioria das pessoas tem em mente hoje foi padronizada por Arthur Benton e Kerry Hamsher em 1976 como o Controlled Oral Word Association Test, usando os agora famosos conjuntos de letras FAS e CFL. Espalhou-se depressa pela neuropsicologia como uma sonda r\xe1pida e sens\xedvel da fun\xe7\xe3o frontal e da linguagem, e continua a ser um dos testes mais aplicados da \xe1rea.",creator:"Arthur L. Benton e Kerry deS. Hamsher, que formalizaram o Controlled Oral Word Association Test (COWAT) dentro do Multilingual Aphasia Examination em 1976. A ideia de fundo \xe9 mais antiga: a tarefa escrita de flu\xeancia de palavras foi criada por Louis Thurstone em 1938, por isso o COWAT \xe9 mais bem descrito como o descendente cl\xednico padronizado do trabalho de Thurstone do que como uma inven\xe7\xe3o do zero.",methods:"Duas estrat\xe9gias dominam o bom desempenho: agrupar (explorar um nicho fon\xe9tico ou sem\xe2ntico de cada vez \u2014 para F: 'f\xe1cil, faca, falar, fazer' e depois 'feij\xe3o, fim, foca') e alternar (saltar para um nicho novo no instante em que a produ\xe7\xe3o desacelera). Use prefixos e fam\xedlias de rima como pontos de partida, percorra os encontros consonantais comuns (fl-, fr-, pr-, tr-) e n\xe3o trave por causa da qualidade \u2014 a quantidade \xe9 que vence, ent\xe3o solte a palavra e siga em frente. Anote as suas letras fracas e treine-as.",duration:"Cada rodada dura 60 segundos, ent\xe3o cabe em qualquer lugar. Uma sess\xe3o \xfatil s\xe3o 5 a 10 letras com pausas curtas, algumas vezes por semana; voc\xea ver\xe1 as suas contagens subirem com relativa rapidez. Como na maioria dessas tarefas, os retornos achatam depois de algumas semanas, ent\xe3o alterne as letras e acrescente as variantes abaixo para continuar desafiado, em vez de insistir no mesmo est\xedmulo.",research:"O que est\xe1 solidamente estabelecido \xe9 que o COWAT \xe9 uma medida cl\xednica fi\xe1vel e bem validada, e que com a pr\xe1tica voc\xea melhora claramente na pr\xf3pria flu\xeancia. A ressalva honesta \xe9 a transfer\xeancia: as revis\xf5es sobre treino cerebral (como a de Simons e colegas, 2016, e as meta-an\xe1lises de treino de mem\xf3ria de trabalho) concluem que os ganhos nas tarefas treinadas raramente se estendem \xe0 intelig\xeancia geral, ao racioc\xednio do dia a dia ou \xe0 prote\xe7\xe3o contra o decl\xednio ligado \xe0 idade. Encare como n\xe3o comprovadas as alega\xe7\xf5es de que 'aumenta o QI' ou 'previne a dem\xeancia' \u2014 o benef\xedcio confi\xe1vel \xe9 uma busca de palavras mais r\xe1pida e flex\xedvel.",rec:"Escolha tr\xeas letras por dia, cumpra 60 segundos em cada uma e conte em voz baixa \u2014 falar as palavras imp\xf5e o ritmo de recuperar-e-seguir-em-frente que \xe9 o verdadeiro alvo do exerc\xedcio.",faq:[["Em que isto difere de nomear animais ou outras categorias?","A flu\xeancia por letra (fon\xe9mica) faz voc\xea buscar pelo som da palavra, o que for\xe7a uma altern\xe2ncia de estrat\xe9gia mais deliberada e apoia-se no controle executivo frontal; a flu\xeancia por categoria (sem\xe2ntica) deixa voc\xea surfar nas associa\xe7\xf5es dentro de um tema e recorre mais ao conhecimento de palavras do lobo temporal. A maioria das pessoas pontua um pouco mais alto nas categorias."],["Treinar isto vai me deixar mais inteligente ou mais r\xe1pido na conversa?","Voc\xea vai melhorar de forma fi\xe1vel na pr\xf3pria tarefa de flu\xeancia e pode sentir-se mais r\xe1pido a puxar palavras. Mas a transfer\xeancia ampla para a intelig\xeancia geral ou a fala do dia a dia \xe9 fraca e contestada na investiga\xe7\xe3o, ent\xe3o encare como pr\xe1tica direcionada para a recupera\xe7\xe3o de palavras, n\xe3o como um turbinador de QI."],["Qual \xe9 uma boa pontua\xe7\xe3o?","N\xe3o h\xe1 um n\xfamero \xfanico \u2014 os resultados dependem muito da idade, da escolaridade e da l\xedngua. Como refer\xeancia aproximada para adultos, falantes saud\xe1veis costumam produzir algo na casa dos doze a dezesseis por letra em 60 segundos, mas a compara\xe7\xe3o mais significativa \xe9 com as suas pr\xf3prias rodadas anteriores, e n\xe3o com um alvo fixo."]],variants:"Flu\xeancia sem\xe2ntica (de categoria) \u2014 nomear animais, frutas ou profiss\xf5es em vez de uma letra; apoia-se mais nos arquivos de palavras do lobo temporal do que na altern\xe2ncia frontal. Outras varia\xe7\xf5es: flu\xeancia com letra exclu\xedda (palavras que N\xc3O podem conter uma dada letra), flu\xeancia de a\xe7\xe3o (apenas verbos), restri\xe7\xf5es de duas letras e tarefas de altern\xe2ncia que trocam entre uma letra e uma categoria a cada poucas palavras."},hi:{about:"Phonemic Fluency \u090f\u0915 \u0938\u092e\u092f\u092c\u0926\u094d\u0927 \u0936\u092c\u094d\u0926-\u0928\u093f\u0930\u094d\u092e\u093e\u0923 \u0905\u092d\u094d\u092f\u093e\u0938 \u0939\u0948: \u0906\u092a\u0915\u094b \u090f\u0915 \u0905\u0915\u0947\u0932\u093e \u0905\u0915\u094d\u0937\u0930 \u0926\u093f\u092f\u093e \u091c\u093e\u0924\u093e \u0939\u0948 \u0914\u0930 \u090f\u0915 \u0924\u092f \u0938\u092e\u092f \u092e\u0947\u0902, \u0906\u092e\u0924\u094c\u0930 \u092a\u0930 60 \u0938\u0947\u0915\u0902\u0921 \u092e\u0947\u0902, \u0909\u0938\u0938\u0947 \u0936\u0941\u0930\u0942 \u0939\u094b\u0928\u0947 \u0935\u093e\u0932\u0947 \u091c\u093f\u0924\u0928\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0936\u092c\u094d\u0926 \u0939\u094b \u0938\u0915\u0947\u0902 \u092c\u094b\u0932\u0928\u0947 \u092f\u093e \u091f\u093e\u0907\u092a \u0915\u0930\u0928\u0947 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902\u0964 \u0935\u094d\u092f\u0915\u094d\u0924\u093f\u0935\u093e\u091a\u0915 \u0928\u093e\u092e, \u0938\u0902\u0916\u094d\u092f\u093e\u090f\u0901 \u0914\u0930 \u090f\u0915 \u0939\u0940 \u0936\u092c\u094d\u0926 \u0915\u0947 \u092c\u0926\u0932\u0947 \u0939\u0941\u090f \u0930\u0942\u092a (run, running, ran) \u0928\u0939\u0940\u0902 \u0917\u093f\u0928\u0947 \u091c\u093e\u0924\u0947, \u0907\u0938\u0932\u093f\u090f \u0905\u0938\u0932\u0940 \u0916\u0947\u0932 \u092f\u0939 \u0939\u0948 \u0915\u093f \u0906\u092a \u0905\u092a\u0928\u0947 \u0936\u092c\u094d\u0926-\u092d\u0902\u0921\u093e\u0930 \u0915\u094b \u0927\u094d\u0935\u0928\u093f \u0915\u0947 \u0938\u0939\u093e\u0930\u0947 \u091f\u091f\u094b\u0932\u0947\u0902 \u0914\u0930 \u0938\u093e\u0925 \u0939\u0940 \u092f\u093e\u0926 \u0930\u0916\u0947\u0902 \u0915\u093f \u092a\u0939\u0932\u0947 \u0915\u094d\u092f\u093e \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0915\u0930 \u091a\u0941\u0915\u0947 \u0939\u0948\u0902\u0964",benefit:"\u092f\u0939 \u092e\u0941\u0916\u094d\u092f \u0930\u0942\u092a \u0938\u0947 \u092d\u093e\u0937\u093e \u092a\u0930 \u0915\u093e\u0930\u094d\u092f\u0915\u093e\u0930\u0940 \u0928\u093f\u092f\u0902\u0924\u094d\u0930\u0923 \u0915\u094b \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u093f\u0924 \u0915\u0930\u0924\u093e \u0939\u0948 \u2014 \u092f\u093e\u0928\u0940 \u092e\u093e\u0901\u0917 \u092a\u0921\u093c\u0924\u0947 \u0939\u0940 \u0916\u094b\u091c \u0936\u0941\u0930\u0942 \u0915\u0930\u0928\u0947, \u090f\u0915 \u0928\u0938 \u0938\u0942\u0916\u0928\u0947 \u092a\u0930 \u0936\u092c\u094d\u0926-\u0938\u092e\u0942\u0939\u094b\u0902 \u0915\u0947 \u092c\u0940\u091a \u092c\u0926\u0932\u0928\u0947, \u091c\u0932\u094d\u0926\u0940 \u0938\u0947 \u0936\u092c\u094d\u0926 \u0922\u0942\u0901\u0922 \u0928\u093f\u0915\u093e\u0932\u0928\u0947, \u0914\u0930 \u0926\u094b\u0939\u0930\u093e\u0935 \u0924\u0925\u093e \u0935\u0930\u094d\u091c\u093f\u0924 \u091c\u0935\u093e\u092c\u094b\u0902 \u0915\u094b \u0930\u094b\u0915\u0928\u0947 \u0915\u0940 \u0915\u094d\u0937\u092e\u0924\u093e\u0964 \u092f\u0939 \u0915\u091a\u094d\u091a\u0947 \u0936\u092c\u094d\u0926-\u092d\u0902\u0921\u093e\u0930 \u0915\u0947 \u0906\u0915\u093e\u0930 \u0938\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u092b\u093c\u094d\u0930\u0902\u091f\u0932-\u0932\u094b\u092c \u0915\u0940 \u0938\u094d\u0935-\u0935\u094d\u092f\u0935\u0938\u094d\u0925\u093e \u092a\u0930 \u091f\u093f\u0915\u093e \u0939\u0948, \u092f\u0939\u0940 \u0935\u091c\u0939 \u0939\u0948 \u0915\u093f \u092f\u0939 '\u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0936\u092c\u094d\u0926 \u091c\u093e\u0928\u0928\u0947' \u0915\u0947 \u092c\u091c\u093e\u092f \u092e\u093e\u0928\u0938\u093f\u0915 \u0932\u091a\u0940\u0932\u0947\u092a\u0928 \u0914\u0930 \u0938\u094d\u0935-\u0928\u093f\u0917\u0930\u093e\u0928\u0940 \u092a\u0930 \u091c\u093c\u094b\u0930 \u0921\u093e\u0932\u0924\u093e \u0939\u0948\u0964",history:"\u0905\u0915\u094d\u0937\u0930-\u0906\u0927\u093e\u0930\u093f\u0924 \u0936\u092c\u094d\u0926-\u092a\u094d\u0930\u0935\u093e\u0939 \u0915\u0940 \u091c\u0921\u093c\u0947\u0902 Louis Thurstone \u0915\u0947 \u0932\u093f\u0916\u093f\u0924 Word Fluency Test (1938) \u0924\u0915 \u091c\u093e\u0924\u0940 \u0939\u0948\u0902, \u091c\u094b \u0909\u0928\u0915\u0947 Primary Mental Abilities \u0915\u093e\u0930\u094d\u092f \u0915\u093e \u0939\u093f\u0938\u094d\u0938\u093e \u0925\u093e\u0964 \u0906\u091c \u091c\u093c\u094d\u092f\u093e\u0926\u093e\u0924\u0930 \u0932\u094b\u0917 \u091c\u093f\u0938 \u092e\u094c\u0916\u093f\u0915 \u0915\u094d\u0932\u093f\u0928\u093f\u0915\u0932 \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0915\u0940 \u092c\u093e\u0924 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902 \u0909\u0938\u0947 Arthur Benton \u0914\u0930 Kerry Hamsher \u0928\u0947 1976 \u092e\u0947\u0902 Controlled Oral Word Association Test \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u092e\u093e\u0928\u0915\u0940\u0915\u0943\u0924 \u0915\u093f\u092f\u093e, \u091c\u093f\u0938\u092e\u0947\u0902 \u0905\u092c \u092e\u0936\u0939\u0942\u0930 FAS \u0914\u0930 CFL \u0905\u0915\u094d\u0937\u0930-\u0938\u092e\u0942\u0939 \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0939\u0941\u090f\u0964 \u092f\u0939 \u0928\u094d\u092f\u0942\u0930\u094b\u0938\u093e\u0907\u0915\u094b\u0932\u0949\u091c\u0940 \u092e\u0947\u0902 \u092b\u093c\u094d\u0930\u0902\u091f\u0932 \u0914\u0930 \u092d\u093e\u0937\u093e-\u0915\u093e\u0930\u094d\u092f \u0915\u0940 \u090f\u0915 \u0924\u094d\u0935\u0930\u093f\u0924, \u0938\u0902\u0935\u0947\u0926\u0928\u0936\u0940\u0932 \u091c\u093e\u0901\u091a \u0915\u0947 \u0924\u094c\u0930 \u092a\u0930 \u0924\u0947\u091c\u093c\u0940 \u0938\u0947 \u092b\u0948\u0932\u093e \u0914\u0930 \u0906\u091c \u092d\u0940 \u0907\u0938 \u0915\u094d\u0937\u0947\u0924\u094d\u0930 \u0915\u0947 \u0938\u092c\u0938\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0926\u093f\u090f \u091c\u093e\u0928\u0947 \u0935\u093e\u0932\u0947 \u092a\u0930\u0940\u0915\u094d\u0937\u0923\u094b\u0902 \u092e\u0947\u0902 \u0938\u0947 \u090f\u0915 \u0939\u0948\u0964",creator:"Arthur L. Benton \u0914\u0930 Kerry deS. Hamsher, \u091c\u093f\u0928\u094d\u0939\u094b\u0902\u0928\u0947 1976 \u092e\u0947\u0902 Multilingual Aphasia Examination \u0915\u0947 \u092d\u0940\u0924\u0930 Controlled Oral Word Association Test (COWAT) \u0915\u094b \u0914\u092a\u091a\u093e\u0930\u093f\u0915 \u0930\u0942\u092a \u0926\u093f\u092f\u093e\u0964 \u092e\u0942\u0932 \u0935\u093f\u091a\u093e\u0930 \u0907\u0938\u0938\u0947 \u092a\u0941\u0930\u093e\u0928\u093e \u0939\u0948: \u0932\u093f\u0916\u093f\u0924 \u0936\u092c\u094d\u0926-\u092a\u094d\u0930\u0935\u093e\u0939 \u0915\u093e\u0930\u094d\u092f Louis Thurstone \u0928\u0947 1938 \u092e\u0947\u0902 \u092c\u0928\u093e\u092f\u093e \u0925\u093e, \u0907\u0938\u0932\u093f\u090f COWAT \u0915\u094b \u0936\u0942\u0928\u094d\u092f \u0938\u0947 \u0915\u093f\u092f\u093e \u0917\u092f\u093e \u0906\u0935\u093f\u0937\u094d\u0915\u093e\u0930 \u0915\u0939\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f Thurstone \u0915\u0947 \u0915\u093e\u092e \u0915\u093e \u092e\u093e\u0928\u0915\u0940\u0915\u0943\u0924 \u0915\u094d\u0932\u093f\u0928\u093f\u0915\u0932 \u0935\u0902\u0936\u091c \u0915\u0939\u0928\u093e \u0938\u092c\u0938\u0947 \u0920\u0940\u0915 \u0939\u0948\u0964",methods:"\u092e\u091c\u093c\u092c\u0942\u0924 \u092a\u094d\u0930\u0926\u0930\u094d\u0936\u0928 \u092e\u0947\u0902 \u0926\u094b \u0930\u0923\u0928\u0940\u0924\u093f\u092f\u093e\u0901 \u0939\u093e\u0935\u0940 \u0930\u0939\u0924\u0940 \u0939\u0948\u0902: \u0938\u092e\u0942\u0939\u0928 (\u090f\u0915 \u092c\u093e\u0930 \u092e\u0947\u0902 \u090f\u0915 \u0927\u094d\u0935\u0928\u094d\u092f\u093e\u0924\u094d\u092e\u0915 \u092f\u093e \u0905\u0930\u094d\u0925\u0917\u0924 \u091c\u0947\u092c \u0915\u094b \u0916\u0902\u0917\u093e\u0932\u0928\u093e \u2014 F \u0915\u0947 \u0932\u093f\u090f: 'fast, far, fall, fail' \u092b\u093f\u0930 'fish, fin') \u0914\u0930 \u092c\u0926\u0932\u093e\u0935 (\u0906\u0909\u091f\u092a\u0941\u091f \u0927\u0940\u092e\u093e \u092a\u0921\u093c\u0924\u0947 \u0939\u0940 \u0915\u093f\u0938\u0940 \u0924\u093e\u091c\u093c\u093e \u091c\u0947\u092c \u092a\u0930 \u091b\u0932\u093e\u0901\u0917 \u0932\u0917\u093e\u0928\u093e)\u0964 \u0909\u092a\u0938\u0930\u094d\u0917\u094b\u0902 \u0914\u0930 \u0924\u0941\u0915 \u0935\u093e\u0932\u0947 \u092a\u0930\u093f\u0935\u093e\u0930\u094b\u0902 \u0915\u094b \u091b\u0932\u093e\u0901\u0917-\u092a\u091f\u094d\u091f\u0940 \u0915\u0940 \u0924\u0930\u0939 \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0915\u0930\u0947\u0902, \u0906\u092e \u0935\u094d\u092f\u0902\u091c\u0928-\u0938\u0902\u092f\u094b\u0917\u094b\u0902 (fl-, fr-, sp-, st-) \u092e\u0947\u0902 \u0938\u0947 \u092c\u0941\u0939\u093e\u0930 \u0932\u0947\u0902, \u0914\u0930 \u0917\u0941\u0923\u0935\u0924\u094d\u0924\u093e \u092a\u0930 \u092e\u0924 \u0905\u091f\u0915\u0947\u0902 \u2014 \u092e\u093e\u0924\u094d\u0930\u093e \u091c\u0940\u0924\u0924\u0940 \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u091d\u091f \u0938\u0947 \u092c\u094b\u0932\u0947\u0902 \u0914\u0930 \u0906\u0917\u0947 \u092c\u0922\u093c\u0947\u0902\u0964 \u0905\u092a\u0928\u0947 \u0915\u092e\u091c\u093c\u094b\u0930 \u0905\u0915\u094d\u0937\u0930\u094b\u0902 \u092a\u0930 \u0917\u093c\u094c\u0930 \u0915\u0930\u0947\u0902 \u0914\u0930 \u0909\u0928\u094d\u0939\u0940\u0902 \u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0930\u0947\u0902\u0964",duration:"\u090f\u0915 \u0930\u093e\u0909\u0902\u0921 60 \u0938\u0947\u0915\u0902\u0921 \u0915\u093e \u0939\u094b\u0924\u093e \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u092f\u0939 \u0915\u0939\u0940\u0902 \u092d\u0940 \u092b\u093c\u093f\u091f \u0939\u094b \u091c\u093e\u0924\u093e \u0939\u0948\u0964 \u090f\u0915 \u0909\u092a\u092f\u094b\u0917\u0940 \u0938\u0924\u094d\u0930 \u0939\u0948 \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u0915\u0941\u091b\u0947\u0915 \u092c\u093e\u0930 \u091b\u094b\u091f\u0947-\u091b\u094b\u091f\u0947 \u0935\u093f\u0930\u093e\u092e\u094b\u0902 \u0915\u0947 \u0938\u093e\u0925 5\u201310 \u0905\u0915\u094d\u0937\u0930; \u0906\u092a \u0905\u092a\u0928\u0940 \u0917\u093f\u0928\u0924\u0940 \u0915\u094b \u0915\u093e\u092b\u093c\u0940 \u091c\u0932\u094d\u0926\u0940 \u091a\u0922\u093c\u0924\u0947 \u0926\u0947\u0916\u0947\u0902\u0917\u0947\u0964 \u091c\u093c\u094d\u092f\u093e\u0926\u093e\u0924\u0930 \u0910\u0938\u0947 \u0915\u093e\u0930\u094d\u092f\u094b\u0902 \u0915\u0940 \u0924\u0930\u0939, \u0915\u0941\u091b \u0939\u092b\u093c\u094d\u0924\u094b\u0902 \u092c\u093e\u0926 \u092b\u093c\u093e\u092f\u0926\u0947 \u0920\u0939\u0930 \u091c\u093e\u0924\u0947 \u0939\u0948\u0902, \u0907\u0938\u0932\u093f\u090f \u090f\u0915 \u0939\u0940 \u092a\u094d\u0930\u0949\u092e\u094d\u092a\u094d\u091f \u0930\u091f\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u0905\u0915\u094d\u0937\u0930 \u092c\u0926\u0932\u0924\u0947 \u0930\u0939\u0947\u0902 \u0914\u0930 \u0928\u0940\u091a\u0947 \u0926\u093f\u090f \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u091c\u094b\u0921\u093c\u0924\u0947 \u0930\u0939\u0947\u0902 \u0924\u093e\u0915\u093f \u091a\u0941\u0928\u094c\u0924\u0940 \u092c\u0928\u0940 \u0930\u0939\u0947\u0964",research:"\u091c\u094b \u092c\u093e\u0924 \u092a\u0941\u0916\u093c\u094d\u0924\u093e \u0924\u0930\u0940\u0915\u0947 \u0938\u0947 \u0938\u094d\u0925\u093e\u092a\u093f\u0924 \u0939\u0948 \u0935\u0939 \u092f\u0939 \u0939\u0948 \u0915\u093f COWAT \u090f\u0915 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926, \u0905\u091a\u094d\u091b\u0940 \u0924\u0930\u0939 \u092e\u093e\u0928\u094d\u092f \u0915\u094d\u0932\u093f\u0928\u093f\u0915\u0932 \u092e\u093e\u092a \u0939\u0948, \u0914\u0930 \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0947 \u0938\u093e\u0925 \u0906\u092a \u0916\u0941\u0926 \u0936\u092c\u094d\u0926-\u092a\u094d\u0930\u0935\u093e\u0939 \u092e\u0947\u0902 \u0938\u093e\u092b\u093c \u0924\u094c\u0930 \u092a\u0930 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902\u0964 \u0908\u092e\u093e\u0928\u0926\u093e\u0930 \u091a\u0947\u0924\u093e\u0935\u0928\u0940 \u0938\u094d\u0925\u093e\u0928\u093e\u0902\u0924\u0930\u0923 \u0915\u094b \u0932\u0947\u0915\u0930 \u0939\u0948: \u092c\u094d\u0930\u0947\u0928-\u091f\u094d\u0930\u0947\u0928\u093f\u0902\u0917 \u0938\u092e\u0940\u0915\u094d\u0937\u093e\u090f\u0901 (\u091c\u0948\u0938\u0947 Simons \u0914\u0930 \u0938\u093e\u0925\u0940, 2016, \u0914\u0930 \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932-\u0938\u094d\u092e\u0943\u0924\u093f \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u0915\u0947 \u092e\u0947\u091f\u093e-\u0935\u093f\u0936\u094d\u0932\u0947\u0937\u0923) \u092a\u093e\u0924\u0940 \u0939\u0948\u0902 \u0915\u093f \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u093f\u0924 \u0915\u093e\u0930\u094d\u092f\u094b\u0902 \u092a\u0930 \u0939\u0941\u090f \u092b\u093c\u093e\u092f\u0926\u0947 \u0936\u093e\u092f\u0926 \u0939\u0940 \u0915\u092d\u0940 \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u092c\u0941\u0926\u094d\u0927\u093f, \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0940 \u0938\u094b\u091a, \u092f\u093e \u0909\u092e\u094d\u0930-\u0938\u0902\u092c\u0902\u0927\u0940 \u0917\u093f\u0930\u093e\u0935\u091f \u0938\u0947 \u092c\u091a\u093e\u0935 \u0924\u0915 \u092b\u0948\u0932\u0924\u0947 \u0939\u0948\u0902\u0964 'IQ \u092c\u0922\u093c\u093e\u0924\u093e \u0939\u0948' \u092f\u093e '\u0921\u093f\u092e\u0947\u0902\u0936\u093f\u092f\u093e \u0930\u094b\u0915\u0924\u093e \u0939\u0948' \u091c\u0948\u0938\u0947 \u0926\u093e\u0935\u094b\u0902 \u0915\u094b \u0905\u092a\u094d\u0930\u092e\u093e\u0923\u093f\u0924 \u092e\u093e\u0928\u0947\u0902 \u2014 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u092b\u093c\u093e\u092f\u0926\u093e \u0924\u094b \u090f\u0915 \u0924\u0947\u091c\u093c, \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0932\u091a\u0940\u0932\u0940 \u0936\u092c\u094d\u0926-\u0916\u094b\u091c \u0939\u0948\u0964",rec:"\u0930\u094b\u091c\u093c \u0924\u0940\u0928 \u0905\u0915\u094d\u0937\u0930 \u091a\u0941\u0928\u0947\u0902, \u0939\u0930 \u090f\u0915 \u0915\u094b 60 \u0938\u0947\u0915\u0902\u0921 \u0926\u0947\u0902, \u0914\u0930 \u0927\u0940\u0930\u0947-\u0927\u0940\u0930\u0947 \u091c\u093c\u094b\u0930 \u0938\u0947 \u0917\u093f\u0928\u0924\u0947 \u091c\u093e\u090f\u0901 \u2014 \u0936\u092c\u094d\u0926\u094b\u0902 \u0915\u094b \u092c\u094b\u0932\u0928\u093e \u0909\u0938 '\u0922\u0942\u0901\u0922\u094b-\u0914\u0930-\u0906\u0917\u0947-\u092c\u0922\u093c\u094b' \u0915\u0940 \u0932\u092f \u0915\u094b \u092e\u091c\u092c\u0942\u0930 \u0915\u0930\u0924\u093e \u0939\u0948 \u091c\u094b \u0907\u0938 \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u093e \u0905\u0938\u0932 \u092e\u0915\u093c\u0938\u0926 \u0939\u0948\u0964",faq:[["\u092f\u0939 \u091c\u093e\u0928\u0935\u0930\u094b\u0902 \u092f\u093e \u0926\u0942\u0938\u0930\u0940 \u0936\u094d\u0930\u0947\u0923\u093f\u092f\u094b\u0902 \u0915\u0947 \u0928\u093e\u092e \u0917\u093f\u0928\u093e\u0928\u0947 \u0938\u0947 \u0915\u0948\u0938\u0947 \u0905\u0932\u0917 \u0939\u0948?","\u0905\u0915\u094d\u0937\u0930 (\u092b\u094b\u0928\u0947\u092e\u093f\u0915) \u092a\u094d\u0930\u0935\u093e\u0939 \u0906\u092a\u0915\u094b \u0907\u0938 \u0906\u0927\u093e\u0930 \u092a\u0930 \u0916\u094b\u091c\u0928\u0947 \u092a\u0930 \u092e\u091c\u092c\u0942\u0930 \u0915\u0930\u0924\u093e \u0939\u0948 \u0915\u093f \u0936\u092c\u094d\u0926 \u0915\u0948\u0938\u093e \u0938\u0941\u0928\u093e\u0908 \u0926\u0947\u0924\u093e \u0939\u0948, \u091c\u094b \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0938\u094b\u091a\u0940-\u0938\u092e\u091d\u0940 \u0930\u0923\u0928\u0940\u0924\u093f-\u092c\u0926\u0932\u0940 \u0915\u0930\u093e\u0924\u093e \u0939\u0948 \u0914\u0930 \u092b\u093c\u094d\u0930\u0902\u091f\u0932 \u0915\u093e\u0930\u094d\u092f\u0915\u093e\u0930\u0940 \u0928\u093f\u092f\u0902\u0924\u094d\u0930\u0923 \u092a\u0930 \u091f\u093f\u0915\u0924\u093e \u0939\u0948; \u0936\u094d\u0930\u0947\u0923\u0940 (\u0905\u0930\u094d\u0925\u0917\u0924) \u092a\u094d\u0930\u0935\u093e\u0939 \u0906\u092a\u0915\u094b \u0915\u093f\u0938\u0940 \u0935\u093f\u0937\u092f \u0915\u0947 \u092d\u0940\u0924\u0930 \u0938\u093e\u0939\u091a\u0930\u094d\u092f\u094b\u0902 \u092a\u0930 \u092c\u0939\u0928\u0947 \u0926\u0947\u0924\u093e \u0939\u0948 \u0914\u0930 \u091f\u0947\u092e\u094d\u092a\u094b\u0930\u0932-\u0932\u094b\u092c \u0915\u0947 \u0936\u092c\u094d\u0926-\u091c\u094d\u091e\u093e\u0928 \u092a\u0930 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0916\u0940\u0902\u091a\u0924\u093e \u0939\u0948\u0964 \u091c\u093c\u094d\u092f\u093e\u0926\u093e\u0924\u0930 \u0932\u094b\u0917 \u0936\u094d\u0930\u0947\u0923\u093f\u092f\u094b\u0902 \u092a\u0930 \u0925\u094b\u0921\u093c\u093e \u090a\u0901\u091a\u093e \u0938\u094d\u0915\u094b\u0930 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902\u0964"],["\u0915\u094d\u092f\u093e \u0907\u0938\u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u092e\u0941\u091d\u0947 \u0939\u094b\u0936\u093f\u092f\u093e\u0930 \u092f\u093e \u092c\u093e\u0924\u091a\u0940\u0924 \u092e\u0947\u0902 \u0924\u0947\u091c\u093c \u092c\u0928\u093e \u0926\u0947\u0917\u093e?","\u0906\u092a \u0916\u0941\u0926 \u0936\u092c\u094d\u0926-\u092a\u094d\u0930\u0935\u093e\u0939 \u0915\u093e\u0930\u094d\u092f \u092e\u0947\u0902 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0930\u0942\u092a \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b\u0902\u0917\u0947 \u0914\u0930 \u0936\u093e\u092f\u0926 \u0936\u092c\u094d\u0926 \u0916\u0940\u0902\u091a \u0928\u093f\u0915\u093e\u0932\u0928\u0947 \u092e\u0947\u0902 \u0924\u0947\u091c\u093c \u092e\u0939\u0938\u0942\u0938 \u0915\u0930\u0947\u0902\u0917\u0947\u0964 \u092a\u0930 \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u092c\u0941\u0926\u094d\u0927\u093f \u092f\u093e \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0940 \u092c\u094b\u0932\u0940 \u0924\u0915 \u0935\u094d\u092f\u093e\u092a\u0915 \u092b\u0948\u0932\u093e\u0935 \u0936\u094b\u0927 \u092e\u0947\u0902 \u0915\u092e\u091c\u093c\u094b\u0930 \u0914\u0930 \u0935\u093f\u0935\u093e\u0926\u093f\u0924 \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0907\u0938\u0947 \u0936\u092c\u094d\u0926-\u092a\u0941\u0928\u0903\u092a\u094d\u0930\u093e\u092a\u094d\u0924\u093f \u0915\u093e \u0932\u0915\u094d\u0937\u093f\u0924 \u0905\u092d\u094d\u092f\u093e\u0938 \u092e\u093e\u0928\u0947\u0902, IQ \u092c\u0922\u093c\u093e\u0928\u0947 \u0935\u093e\u0932\u093e \u0938\u093e\u0927\u0928 \u0928\u0939\u0940\u0902\u0964"],["\u0905\u091a\u094d\u091b\u093e \u0938\u094d\u0915\u094b\u0930 \u0915\u094d\u092f\u093e \u0939\u094b\u0924\u093e \u0939\u0948?","\u0915\u094b\u0908 \u090f\u0915 \u0938\u0902\u0916\u094d\u092f\u093e \u0928\u0939\u0940\u0902 \u0939\u0948 \u2014 \u0928\u0924\u0940\u091c\u0947 \u0909\u092e\u094d\u0930, \u0936\u093f\u0915\u094d\u0937\u093e \u0914\u0930 \u092d\u093e\u0937\u093e \u092a\u0930 \u092c\u0939\u0941\u0924 \u0928\u093f\u0930\u094d\u092d\u0930 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902\u0964 \u092e\u094b\u091f\u0947 \u0924\u094c\u0930 \u092a\u0930 \u090f\u0915 \u0935\u092f\u0938\u094d\u0915 \u0938\u0902\u0926\u0930\u094d\u092d \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902, \u0938\u094d\u0935\u0938\u094d\u0925 \u0935\u0915\u094d\u0924\u093e \u0905\u0915\u0938\u0930 60 \u0938\u0947\u0915\u0902\u0921 \u092e\u0947\u0902 \u092a\u094d\u0930\u0924\u093f \u0905\u0915\u094d\u0937\u0930 \u092a\u0902\u0926\u094d\u0930\u0939 \u0915\u0947 \u0906\u0938\u092a\u093e\u0938 \u0936\u092c\u094d\u0926 \u092c\u094b\u0932 \u0932\u0947\u0924\u0947 \u0939\u0948\u0902, \u092a\u0930 \u0938\u092c\u0938\u0947 \u0938\u093e\u0930\u094d\u0925\u0915 \u0924\u0941\u0932\u0928\u093e \u0915\u093f\u0938\u0940 \u0924\u092f \u0932\u0915\u094d\u0937\u094d\u092f \u0938\u0947 \u0928\u0939\u0940\u0902, \u092c\u0932\u094d\u0915\u093f \u0906\u092a\u0915\u0947 \u0905\u092a\u0928\u0947 \u092a\u093f\u091b\u0932\u0947 \u0930\u093e\u0909\u0902\u0921 \u0938\u0947 \u0939\u0948\u0964"]],variants:"\u0905\u0930\u094d\u0925\u0917\u0924 (\u0936\u094d\u0930\u0947\u0923\u0940) \u092a\u094d\u0930\u0935\u093e\u0939 \u2014 \u0905\u0915\u094d\u0937\u0930 \u0915\u0947 \u092c\u091c\u093e\u092f \u091c\u093e\u0928\u0935\u0930, \u092b\u0932 \u092f\u093e \u092a\u0947\u0936\u0947 \u0917\u093f\u0928\u093e\u0928\u093e; \u092f\u0939 \u092b\u093c\u094d\u0930\u0902\u091f\u0932 \u092c\u0926\u0932\u093e\u0935 \u0938\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u091f\u0947\u092e\u094d\u092a\u094b\u0930\u0932-\u0932\u094b\u092c \u0915\u0947 \u0936\u092c\u094d\u0926-\u092d\u0902\u0921\u093e\u0930 \u092a\u0930 \u091f\u093f\u0915\u0924\u093e \u0939\u0948\u0964 \u0905\u0928\u094d\u092f \u092a\u0947\u091a: \u0935\u0930\u094d\u091c\u093f\u0924-\u0905\u0915\u094d\u0937\u0930 \u092a\u094d\u0930\u0935\u093e\u0939 (\u0910\u0938\u0947 \u0936\u092c\u094d\u0926 \u091c\u093f\u0928\u092e\u0947\u0902 \u0915\u094b\u0908 \u0926\u093f\u092f\u093e \u0917\u092f\u093e \u0905\u0915\u094d\u0937\u0930 \u0928 \u0939\u094b), \u0915\u094d\u0930\u093f\u092f\u093e \u092a\u094d\u0930\u0935\u093e\u0939 (\u0938\u093f\u0930\u094d\u092b\u093c \u0915\u094d\u0930\u093f\u092f\u093e\u090f\u0901), \u0926\u094b-\u0905\u0915\u094d\u0937\u0930 \u0935\u093e\u0932\u0940 \u0936\u0930\u094d\u0924\u0947\u0902, \u0914\u0930 \u092c\u0926\u0932\u093e\u0935 \u0935\u093e\u0932\u0947 \u0915\u093e\u0930\u094d\u092f \u091c\u094b \u0939\u0930 \u0915\u0941\u091b \u0936\u092c\u094d\u0926\u094b\u0902 \u092a\u0930 \u0905\u0915\u094d\u0937\u0930 \u0914\u0930 \u0936\u094d\u0930\u0947\u0923\u0940 \u0915\u0947 \u092c\u0940\u091a \u092b\u0947\u0930\u092c\u0926\u0932 \u0915\u0930\u0924\u0947 \u0930\u0939\u0924\u0947 \u0939\u0948\u0902\u0964"},zh:{about:"\u97f3\u4f4d\u6d41\u7545\u6027\u662f\u4e00\u9879\u9650\u65f6\u7684\u8bcd\u8bed\u751f\u6210\u7ec3\u4e60\uff1a\u7ed9\u4f60\u4e00\u4e2a\u5b57\u6bcd\uff0c\u4f60\u8981\u5728\u56fa\u5b9a\u7684\u7a97\u53e3\u5185\uff08\u901a\u5e38\u662f 60 \u79d2\uff09\u5c3d\u91cf\u591a\u5730\u8bf4\u51fa\u6216\u6253\u51fa\u4ee5\u5b83\u5f00\u5934\u7684\u5355\u8bcd\u3002\u4e13\u6709\u540d\u8bcd\u3001\u6570\u5b57\u4ee5\u53ca\u540c\u4e00\u4e2a\u8bcd\u7684\u91cd\u590d\u53d8\u5f62\uff08run\u3001running\u3001ran\uff09\u90fd\u4e0d\u7b97\uff0c\u6240\u4ee5\u771f\u6b63\u7684\u73a9\u6cd5\u662f\u6309\u8bfb\u97f3\u5728\u8bcd\u6c47\u5e93\u91cc\u641c\u7d22\uff0c\u540c\u65f6\u8bb0\u4f4f\u81ea\u5df1\u5df2\u7ecf\u7528\u8fc7\u54ea\u4e9b\u3002",benefit:"\u5b83\u4e3b\u8981\u8bad\u7ec3\u5bf9\u8bed\u8a00\u7684\u6267\u884c\u63a7\u5236\u2014\u2014\u6309\u9700\u542f\u52a8\u4e00\u6b21\u641c\u7d22\u3001\u5728\u4e00\u6761\u300c\u77ff\u8109\u300d\u67af\u7aed\u65f6\u5207\u6362\u5230\u53e6\u4e00\u7ec4\u8bcd\u3001\u5feb\u901f\u63d0\u53d6\uff0c\u4ee5\u53ca\u6291\u5236\u91cd\u590d\u548c\u88ab\u7981\u6b62\u7684\u7b54\u6848\u3002\u5b83\u66f4\u4f9d\u8d56\u989d\u53f6\u7684\u81ea\u6211\u7ec4\u7ec7\uff0c\u800c\u4e0d\u662f\u8bcd\u6c47\u91cf\u7684\u5927\u5c0f\uff0c\u8fd9\u5c31\u662f\u4e3a\u4ec0\u4e48\u5b83\u8003\u9a8c\u7684\u662f\u5fc3\u7406\u7075\u6d3b\u6027\u548c\u81ea\u6211\u76d1\u63a7\uff0c\u800c\u4e0d\u4ec5\u4ec5\u662f\u300c\u8ba4\u8bc6\u66f4\u591a\u8bcd\u300d\u3002",history:"\u57fa\u4e8e\u5b57\u6bcd\u7684\u8bcd\u8bed\u6d41\u7545\u6027\u53ef\u8ffd\u6eaf\u5230 Louis Thurstone \u7684\u4e66\u9762\u8bcd\u8bed\u6d41\u7545\u6027\u6d4b\u9a8c\uff081938 \u5e74\uff09\uff0c\u90a3\u662f\u4ed6\u300c\u57fa\u672c\u5fc3\u7406\u80fd\u529b\u300d\u5de5\u4f5c\u7684\u4e00\u90e8\u5206\u3002\u5982\u4eca\u5927\u591a\u6570\u4eba\u6240\u6307\u7684\u53e3\u5934\u4e34\u5e8a\u7248\u672c\uff0c\u7531 Arthur Benton \u548c Kerry Hamsher \u4e8e 1976 \u5e74\u6807\u51c6\u5316\uff0c\u5b9a\u540d\u4e3a\u53d7\u63a7\u53e3\u5934\u8bcd\u8bed\u8054\u60f3\u6d4b\u9a8c\uff08Controlled Oral Word Association Test\uff09\uff0c\u4f7f\u7528\u4e86\u5982\u4eca\u8457\u540d\u7684 FAS \u548c CFL \u5b57\u6bcd\u7ec4\u3002\u5b83\u5f88\u5feb\u5728\u795e\u7ecf\u5fc3\u7406\u5b66\u754c\u4f20\u5f00\uff0c\u6210\u4e3a\u5feb\u901f\u800c\u654f\u611f\u5730\u63a2\u67e5\u989d\u53f6\u4e0e\u8bed\u8a00\u529f\u80fd\u7684\u5de5\u5177\uff0c\u81f3\u4eca\u4ecd\u662f\u8be5\u9886\u57df\u65bd\u6d4b\u6700\u5e7f\u7684\u6d4b\u9a8c\u4e4b\u4e00\u3002",creator:"Arthur L. Benton \u548c Kerry deS. Hamsher\uff0c\u4ed6\u4eec\u4e8e 1976 \u5e74\u5728\u591a\u8bed\u5931\u8bed\u75c7\u68c0\u67e5\uff08Multilingual Aphasia Examination\uff09\u4e2d\u5c06\u53d7\u63a7\u53e3\u5934\u8bcd\u8bed\u8054\u60f3\u6d4b\u9a8c\uff08COWAT\uff09\u6b63\u5f0f\u786e\u7acb\u3002\u5176\u5e95\u5c42\u601d\u8def\u66f4\u4e3a\u53e4\u8001\uff1a\u4e66\u9762\u8bcd\u8bed\u6d41\u7545\u6027\u4efb\u52a1\u7531 Louis Thurstone \u4e8e 1938 \u5e74\u521b\u5236\uff0c\u6240\u4ee5 COWAT \u6700\u597d\u88ab\u63cf\u8ff0\u4e3a Thurstone \u5de5\u4f5c\u7684\u6807\u51c6\u5316\u4e34\u5e8a\u540e\u4ee3\uff0c\u800c\u975e\u51ed\u7a7a\u7684\u53d1\u660e\u3002",methods:"\u51fa\u8272\u8868\u73b0\u4e3b\u8981\u9760\u4e24\u79cd\u7b56\u7565\uff1a\u805a\u7c7b\uff08\u4e00\u6b21\u53ea\u6316\u4e00\u4e2a\u8bed\u97f3\u6216\u8bed\u4e49\u53e3\u888b\u2014\u2014\u4ee5 F \u4e3a\u4f8b\uff1a\u5148\u300cfast\u3001far\u3001fall\u3001fail\u300d\uff0c\u518d\u300cfish\u3001fin\u300d\uff09\u548c\u5207\u6362\uff08\u4e00\u65e6\u4ea7\u51fa\u53d8\u6162\uff0c\u7acb\u523b\u8df3\u5230\u4e00\u4e2a\u5168\u65b0\u7684\u53e3\u888b\uff09\u3002\u628a\u524d\u7f00\u548c\u62bc\u97f5\u8bcd\u65cf\u5f53\u4f5c\u53d1\u5c04\u53f0\uff0c\u626b\u8fc7\u5e38\u89c1\u7684\u8f85\u97f3\u8fde\u7f00\uff08fl-\u3001fr-\u3001sp-\u3001st-\uff09\uff0c\u522b\u5728\u8d28\u91cf\u4e0a\u5361\u58f3\u2014\u2014\u6570\u91cf\u53d6\u80dc\uff0c\u6240\u4ee5\u8131\u53e3\u800c\u51fa\u518d\u7ee7\u7eed\u3002\u8bb0\u4e0b\u4f60\u8584\u5f31\u7684\u5b57\u6bcd\uff0c\u4e13\u95e8\u7ec3\u90a3\u4e9b\u3002",duration:"\u5355\u8f6e 60 \u79d2\uff0c\u6240\u4ee5\u968f\u5904\u90fd\u80fd\u585e\u8fdb\u53bb\u3002\u4e00\u6b21\u6709\u7528\u7684\u7ec3\u4e60\u662f 5\u201310 \u4e2a\u5b57\u6bcd\u3001\u4e2d\u95f4\u77ed\u6682\u4f11\u606f\uff0c\u6bcf\u5468\u51e0\u6b21\uff1b\u4f60\u4f1a\u770b\u5230\u81ea\u5df1\u7684\u8ba1\u6570\u76f8\u5f53\u5feb\u5730\u5f80\u4e0a\u722c\u3002\u548c\u5927\u591a\u6570\u8fd9\u7c7b\u4efb\u52a1\u4e00\u6837\uff0c\u51e0\u5468\u540e\u6536\u76ca\u4f1a\u53d8\u5e73\uff0c\u6240\u4ee5\u8f6e\u6362\u5b57\u6bcd\u3001\u52a0\u4e0a\u4e0b\u9762\u7684\u53d8\u4f53\u6765\u4fdd\u6301\u6311\u6218\uff0c\u800c\u4e0d\u662f\u6b7b\u78d5\u540c\u4e00\u4e2a\u9898\u76ee\u3002",research:"\u5df2\u88ab\u7a33\u56fa\u786e\u7acb\u7684\u662f\uff1aCOWAT \u662f\u4e00\u9879\u53ef\u9760\u3001\u7ecf\u8fc7\u5145\u5206\u9a8c\u8bc1\u7684\u4e34\u5e8a\u6d4b\u91cf\uff0c\u800c\u968f\u7740\u7ec3\u4e60\uff0c\u4f60\u5728\u6d41\u7545\u6027\u672c\u8eab\u4e0a\u4f1a\u660e\u663e\u53d8\u597d\u3002\u8bda\u5b9e\u7684\u544a\u8beb\u5728\u4e8e\u8fc1\u79fb\uff1a\u5927\u8111\u8bad\u7ec3\u7efc\u8ff0\uff08\u5982 Simons \u53ca\u540c\u4e8b\uff0c2016 \u5e74\uff0c\u4ee5\u53ca\u5de5\u4f5c\u8bb0\u5fc6\u8bad\u7ec3\u7684\u5143\u5206\u6790\uff09\u53d1\u73b0\uff0c\u5728\u53d7\u8bad\u4efb\u52a1\u4e0a\u7684\u6536\u76ca\u5f88\u5c11\u6269\u6563\u5230\u4e00\u822c\u667a\u529b\u3001\u65e5\u5e38\u601d\u7ef4\u6216\u5bf9\u5e74\u9f84\u76f8\u5173\u8870\u9000\u7684\u4fdd\u62a4\u4e0a\u3002\u628a\u300c\u63d0\u9ad8 IQ\u300d\u6216\u300c\u9884\u9632\u75f4\u5446\u300d\u4e4b\u7c7b\u7684\u8bf4\u6cd5\u5f53\u4f5c\u672a\u7ecf\u8bc1\u5b9e\u2014\u2014\u9760\u5f97\u4f4f\u7684\u597d\u5904\u662f\u66f4\u5feb\u3001\u66f4\u7075\u6d3b\u7684\u8bcd\u8bed\u641c\u7d22\u3002",rec:"\u6bcf\u5929\u6311\u4e09\u4e2a\u5b57\u6bcd\uff0c\u6bcf\u4e2a\u8dd1\u6ee1 60 \u79d2\uff0c\u5e76\u8f7b\u58f0\u628a\u8bcd\u6570\u51fa\u6765\u2014\u2014\u628a\u8bcd\u8bf4\u51fa\u53e3\uff0c\u4f1a\u903c\u51fa\u8fd9\u9879\u7ec3\u4e60\u771f\u6b63\u8981\u7684\u90a3\u79cd\u300c\u63d0\u53d6\u4e86\u5c31\u5f80\u4e0b\u8d70\u300d\u7684\u8282\u594f\u3002",faq:[["\u8fd9\u548c\u8bf4\u52a8\u7269\u6216\u5176\u4ed6\u7c7b\u522b\u6709\u4ec0\u4e48\u4e0d\u540c\uff1f","\u5b57\u6bcd\uff08\u97f3\u4f4d\uff09\u6d41\u7545\u6027\u903c\u4f60\u6309\u4e00\u4e2a\u8bcd\u600e\u4e48\u53d1\u97f3\u53bb\u641c\u7d22\uff0c\u8fd9\u4f1a\u5f3a\u5236\u66f4\u523b\u610f\u7684\u7b56\u7565\u5207\u6362\uff0c\u5e76\u4f9d\u8d56\u989d\u53f6\u6267\u884c\u63a7\u5236\uff1b\u7c7b\u522b\uff08\u8bed\u4e49\uff09\u6d41\u7545\u6027\u5219\u8ba9\u4f60\u987a\u7740\u4e00\u4e2a\u4e3b\u9898\u5185\u90e8\u7684\u8054\u60f3\u5f80\u4e0b\u6ed1\uff0c\u66f4\u591a\u4f9d\u9760\u989e\u53f6\u7684\u8bcd\u8bed\u77e5\u8bc6\u3002\u5927\u591a\u6570\u4eba\u5728\u7c7b\u522b\u4e0a\u7684\u5f97\u5206\u4f1a\u7565\u9ad8\u4e00\u4e9b\u3002"],["\u7ec3\u8fd9\u4e2a\u4f1a\u8ba9\u6211\u66f4\u806a\u660e\u3001\u6216\u5bf9\u8bdd\u65f6\u53cd\u5e94\u66f4\u5feb\u5417\uff1f","\u4f60\u4f1a\u53ef\u9760\u5730\u5728\u6d41\u7545\u6027\u4efb\u52a1\u672c\u8eab\u4e0a\u53d8\u597d\uff0c\u4e5f\u53ef\u80fd\u611f\u89c9\u81ea\u5df1\u63d0\u8bcd\u66f4\u5feb\u3002\u4f46\u80fd\u5426\u5e7f\u6cdb\u8fc1\u79fb\u5230\u4e00\u822c\u667a\u529b\u6216\u65e5\u5e38\u8a00\u8bed\uff0c\u7814\u7a76\u91cc\u8bc1\u636e\u5f88\u5f31\u3001\u6709\u4e89\u8bae\uff0c\u6240\u4ee5\u628a\u5b83\u5f53\u4f5c\u9488\u5bf9\u63d0\u8bcd\u7684\u6709\u7684\u653e\u77e2\u7684\u7ec3\u4e60\uff0c\u800c\u4e0d\u662f IQ \u63d0\u5347\u5668\u3002"],["\u591a\u5c11\u5206\u7b97\u597d\uff1f","\u6ca1\u6709\u5355\u4e00\u6570\u5b57\u2014\u2014\u7ed3\u679c\u5728\u5f88\u5927\u7a0b\u5ea6\u4e0a\u53d6\u51b3\u4e8e\u5e74\u9f84\u3001\u6559\u80b2\u548c\u8bed\u8a00\u3002\u4f5c\u4e3a\u6210\u4eba\u7684\u7c97\u7565\u53c2\u7167\uff0c\u5065\u5eb7\u7684\u6bcd\u8bed\u8005\u5728 60 \u79d2\u5185\u6bcf\u4e2a\u5b57\u6bcd\u5f80\u5f80\u80fd\u4ea7\u51fa\u5341\u51e0\u4e2a\u8bcd\uff0c\u4f46\u6700\u6709\u610f\u4e49\u7684\u6bd4\u8f83\u662f\u548c\u4f60\u81ea\u5df1\u65e9\u4e9b\u65f6\u5019\u7684\u6210\u7ee9\u6bd4\uff0c\u800c\u4e0d\u662f\u67d0\u4e2a\u56fa\u5b9a\u76ee\u6807\u3002"]],variants:"\u8bed\u4e49\uff08\u7c7b\u522b\uff09\u6d41\u7545\u6027\u2014\u2014\u8bf4\u52a8\u7269\u3001\u6c34\u679c\u6216\u804c\u4e1a\uff0c\u800c\u4e0d\u662f\u67d0\u4e2a\u5b57\u6bcd\uff1b\u5b83\u66f4\u4f9d\u8d56\u989e\u53f6\u7684\u8bcd\u8bed\u50a8\u5907\uff0c\u800c\u975e\u989d\u53f6\u7684\u5207\u6362\u3002\u5176\u4ed6\u82b1\u6837\uff1a\u6392\u9664\u5b57\u6bcd\u7684\u6d41\u7545\u6027\uff08\u8bf4\u51fa\u4e0d\u5f97\u5305\u542b\u67d0\u4e2a\u5b57\u6bcd\u7684\u8bcd\uff09\u3001\u52a8\u4f5c\u6d41\u7545\u6027\uff08\u53ea\u8bf4\u52a8\u8bcd\uff09\u3001\u53cc\u5b57\u6bcd\u7ea6\u675f\uff0c\u4ee5\u53ca\u6bcf\u9694\u51e0\u4e2a\u8bcd\u5c31\u5728\u5b57\u6bcd\u548c\u7c7b\u522b\u4e4b\u95f4\u4ea4\u66ff\u7684\u5207\u6362\u4efb\u52a1\u3002"}},"picture-pairs":{ru:{about:"\u0412 \xab\u041f\u0430\u0440\u0430\u0445 \u043a\u0430\u0440\u0442\u0438\u043d\u043e\u043a\xbb \u043a\u0430\u0440\u0442\u043e\u0447\u043a\u0438 \u0440\u0430\u0437\u043b\u043e\u0436\u0435\u043d\u044b \u0440\u0443\u0431\u0430\u0448\u043a\u043e\u0439 \u0432\u0432\u0435\u0440\u0445, \u0438 \u043a\u0430\u0436\u0434\u043e\u0435 \u0438\u0437\u043e\u0431\u0440\u0430\u0436\u0435\u043d\u0438\u0435 \u0432\u0441\u0442\u0440\u0435\u0447\u0430\u0435\u0442\u0441\u044f \u0440\u043e\u0432\u043d\u043e \u0434\u0432\u0430\u0436\u0434\u044b. \u0417\u0430 \u0445\u043e\u0434 \u0432\u044b \u043e\u0442\u043a\u0440\u044b\u0432\u0430\u0435\u0442\u0435 \u0434\u0432\u0435 \u043a\u0430\u0440\u0442\u043e\u0447\u043a\u0438: \u0441\u043e\u0432\u043f\u0430\u043b\u0438 \u2014 \u043f\u0430\u0440\u0430 \u043e\u0441\u0442\u0430\u0451\u0442\u0441\u044f \u043e\u0442\u043a\u0440\u044b\u0442\u043e\u0439 \u0438 \u0443\u0431\u0438\u0440\u0430\u0435\u0442\u0441\u044f, \u043d\u0435 \u0441\u043e\u0432\u043f\u0430\u043b\u0438 \u2014 \u043f\u0435\u0440\u0435\u0432\u043e\u0440\u0430\u0447\u0438\u0432\u0430\u044e\u0442\u0441\u044f \u043e\u0431\u0440\u0430\u0442\u043d\u043e. \u0417\u0430\u0434\u0430\u0447\u0430 \u2014 \u0440\u0430\u0441\u0447\u0438\u0441\u0442\u0438\u0442\u044c \u0432\u0441\u0451 \u043f\u043e\u043b\u0435 \u0437\u0430 \u043a\u0430\u043a \u043c\u043e\u0436\u043d\u043e \u043c\u0435\u043d\u044c\u0448\u0435\u0435 \u0447\u0438\u0441\u043b\u043e \u043e\u0442\u043a\u0440\u044b\u0442\u0438\u0439.",benefit:"\u0418\u0433\u0440\u0430 \u0432 \u043f\u0435\u0440\u0432\u0443\u044e \u043e\u0447\u0435\u0440\u0435\u0434\u044c \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u0443\u044e \u043a\u0440\u0430\u0442\u043a\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u0443\u044e \u0438 \u0440\u0430\u0431\u043e\u0447\u0443\u044e \u043f\u0430\u043c\u044f\u0442\u044c \u2014 \u043d\u0443\u0436\u043d\u043e \u0443\u0434\u0435\u0440\u0436\u0430\u0442\u044c, \u0433\u0434\u0435 \u043b\u0435\u0436\u0430\u043b\u0430 \u043a\u0430\u0440\u0442\u043e\u0447\u043a\u0430, \u0438 \u0441\u043e\u043f\u043e\u0441\u0442\u0430\u0432\u0438\u0442\u044c \u0435\u0451 \u0441 \u0442\u043e\u0439, \u0447\u0442\u043e \u0432\u044b \u0432\u0438\u0434\u0438\u0442\u0435 \u0441\u0435\u0439\u0447\u0430\u0441. \u041f\u043e\u0434\u043a\u043b\u044e\u0447\u0430\u044e\u0442\u0441\u044f \u0442\u0430\u043a\u0436\u0435 \u0443\u0441\u0442\u043e\u0439\u0447\u0438\u0432\u043e\u0435 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u0438 \u043d\u0435\u043c\u043d\u043e\u0433\u043e \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u0430\u044f \u043f\u0430\u043c\u044f\u0442\u044c, \u0432\u0435\u0434\u044c \u0432\u044b \u043e\u0442\u0441\u043b\u0435\u0436\u0438\u0432\u0430\u0435\u0442\u0435 \u0440\u0430\u0441\u043f\u043e\u043b\u043e\u0436\u0435\u043d\u0438\u0435 \u043a\u0430\u0440\u0442\u043e\u0447\u0435\u043a \u043d\u0430 \u043f\u043e\u043b\u0435.",history:"\u0418\u0434\u0435\u044f \u043f\u043e\u0438\u0441\u043a\u0430 \u043f\u0430\u0440 \u043e\u0447\u0435\u043d\u044c \u0434\u0440\u0435\u0432\u043d\u044f\u044f: \u044f\u043f\u043e\u043d\u0441\u043a\u0430\u044f \u0438\u0433\u0440\u0430 \u0432 \u0440\u0430\u043a\u043e\u0432\u0438\u043d\u044b \u043a\u0430\u0439-\u0430\u0432\u0430\u0441\u044d \u0432\u043e\u0441\u0445\u043e\u0434\u0438\u0442 \u043a \u044d\u043f\u043e\u0445\u0435 \u0425\u044d\u0439\u0430\u043d (\u043f\u0440\u0438\u043c\u0435\u0440\u043d\u043e VIII\u2013XII \u0432\u0435\u043a\u0430). \u041a\u0430\u043a \u043a\u0430\u0440\u0442\u043e\u0447\u043d\u0430\u044f \u0438\u0433\u0440\u0430 \u043e\u043d\u0430 \u0440\u0430\u0437\u043e\u0448\u043b\u0430\u0441\u044c \u0432 XX \u0432\u0435\u043a\u0435 \u043f\u043e\u0434 \u043c\u043d\u043e\u0436\u0435\u0441\u0442\u0432\u043e\u043c \u0438\u043c\u0451\u043d \u2014 \u043f\u0435\u043b\u043c\u0430\u043d\u0438\u0437\u043c (\u0437\u0430\u0444\u0438\u043a\u0441\u0438\u0440\u043e\u0432\u0430\u043d \u0432 Hoyle's Games Modernized, 1923), \xab\u041a\u043e\u043d\u0446\u0435\u043d\u0442\u0440\u0430\u0446\u0438\u044f\xbb, \xab\u041f\u0430\u0440\u044b\xbb, \xab\u041f\u0435\u043a\u0441\u0435\u0441\u043e\xbb, \u2014 \u0430 \u0432 \u043a\u043e\u0440\u043e\u0431\u043e\u0447\u043d\u043e\u043c \u0432\u0438\u0434\u0435 \u0435\u0451 \u0441\u0434\u0435\u043b\u0430\u043b\u0430 \u043c\u0430\u0441\u0441\u043e\u0432\u043e\u0439 \u0438\u0433\u0440\u0430 Memory \u043a\u043e\u043c\u043f\u0430\u043d\u0438\u0438 Ravensburger \u0432 1959 \u0433\u043e\u0434\u0443.",creator:"\u0415\u0434\u0438\u043d\u043e\u0433\u043e \u0430\u0432\u0442\u043e\u0440\u0430 \u043d\u0435\u0442. \u042d\u0442\u043e \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u043e\u043d\u043d\u0430\u044f \u0438\u0433\u0440\u0430 \u0438\u0437 \u0448\u0438\u0440\u043e\u043a\u043e\u0433\u043e \u0441\u0435\u043c\u0435\u0439\u0441\u0442\u0432\u0430 \u0438\u0433\u0440 \u043d\u0430 \u043f\u043e\u0438\u0441\u043a \u043f\u0430\u0440, \u043f\u0435\u0440\u0435\u0448\u0435\u0434\u0448\u0430\u044f \u0432 \u043e\u0431\u0449\u0435\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0435 \u0434\u043e\u0441\u0442\u043e\u044f\u043d\u0438\u0435; \u0435\u0451 \u0440\u0430\u043d\u043d\u0438\u0439 \u043f\u0440\u0435\u0434\u043e\u043a \u2014 \u0438\u0433\u0440\u0430 \u0432 \u043f\u0430\u0440\u043d\u044b\u0435 \u0440\u0430\u043a\u043e\u0432\u0438\u043d\u044b \u043a\u0430\u0439-\u0430\u0432\u0430\u0441\u044d \u0432 \u042f\u043f\u043e\u043d\u0438\u0438 \u044d\u043f\u043e\u0445\u0438 \u0425\u044d\u0439\u0430\u043d. \u0418\u0437\u0432\u0435\u0441\u0442\u043d\u0443\u044e \u043a\u043e\u0440\u043e\u0431\u043e\u0447\u043d\u0443\u044e \u0432\u0435\u0440\u0441\u0438\u044e Memory \u0432\u044b\u043f\u0443\u0441\u0442\u0438\u043b Ravensburger \u0432 1959 \u0433\u043e\u0434\u0443, \u043f\u0440\u0438\u0447\u0451\u043c, \u043f\u043e \u0441\u043e\u043e\u0431\u0449\u0435\u043d\u0438\u044f\u043c, \u043e\u043d\u0430 \u0432\u044b\u0440\u043e\u0441\u043b\u0430 \u0438\u0437 \u0441\u0430\u043c\u043e\u0434\u0435\u043b\u044c\u043d\u043e\u0439 \u0441\u0435\u043c\u0435\u0439\u043d\u043e\u0439 \u0438\u0433\u0440\u044b, \u0430 \u043d\u0435 \u0431\u044b\u043b\u0430 \u043f\u0440\u0438\u0434\u0443\u043c\u0430\u043d\u0430 \u043e\u0434\u043d\u0438\u043c \u0447\u0435\u043b\u043e\u0432\u0435\u043a\u043e\u043c \u0441 \u043d\u0443\u043b\u044f.",methods:"\u041d\u0435 \u043e\u0442\u043a\u0440\u044b\u0432\u0430\u0439\u0442\u0435 \u043a\u0430\u0440\u0442\u043e\u0447\u043a\u0438 \u043d\u0430\u0443\u0433\u0430\u0434 \u2014 \u0434\u0435\u0439\u0441\u0442\u0432\u0443\u0439\u0442\u0435 \u0441\u0438\u0441\u0442\u0435\u043c\u043d\u043e, \u043d\u0430\u043f\u0440\u0438\u043c\u0435\u0440 \u0440\u044f\u0434 \u0437\u0430 \u0440\u044f\u0434\u043e\u043c, \u0447\u0442\u043e\u0431\u044b \u043a\u0430\u0436\u0434\u0430\u044f \u043d\u043e\u0432\u0430\u044f \u043a\u0430\u0440\u0442\u043e\u0447\u043a\u0430 \u0434\u0430\u0432\u0430\u043b\u0430 \u043c\u0430\u043a\u0441\u0438\u043c\u0443\u043c \u0438\u043d\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u0438. \u041f\u043e\u043c\u0435\u0447\u0430\u0439\u0442\u0435 \u043e\u0442\u043a\u0440\u044b\u0442\u044b\u0435 \u043a\u0430\u0440\u0442\u043e\u0447\u043a\u0438 \u0441\u043b\u043e\u0432\u043e\u043c \u0438\u043b\u0438 \u043c\u0435\u0441\u0442\u043e\u043c (\xab\u0440\u043e\u0431\u043e\u0442 \u0441\u043b\u0435\u0432\u0430 \u0432\u0432\u0435\u0440\u0445\u0443\xbb), \u043f\u0435\u0440\u0432\u043e\u0439 \u043f\u0435\u0440\u0435\u0432\u043e\u0440\u0430\u0447\u0438\u0432\u0430\u0439\u0442\u0435 \u0442\u0443, \u0432 \u043a\u043e\u0442\u043e\u0440\u043e\u0439 \u043c\u0435\u043d\u044c\u0448\u0435 \u0443\u0432\u0435\u0440\u0435\u043d\u044b, \u0447\u0442\u043e\u0431\u044b \u043d\u0435 \u0442\u0440\u0430\u0442\u0438\u0442\u044c \u0432\u043f\u0443\u0441\u0442\u0443\u044e \u0443\u0436\u0435 \u0438\u0437\u0432\u0435\u0441\u0442\u043d\u0443\u044e \u043f\u0430\u0440\u0443, \u0438 \u0434\u0435\u0440\u0436\u0438\u0442\u0435 \u0440\u043e\u0432\u043d\u044b\u0439 \u0442\u0435\u043c\u043f: \u043e\u0434\u043d\u043e \u043d\u0435\u0431\u0440\u0435\u0436\u043d\u043e\u0435 \u043e\u0442\u043a\u0440\u044b\u0442\u0438\u0435 \u0441\u0431\u0440\u0430\u0441\u044b\u0432\u0430\u0435\u0442 \u043f\u0430\u0440\u0443, \u043a\u043e\u0442\u043e\u0440\u0443\u044e \u0432\u044b \u0443\u0436\u0435 \u0437\u043d\u0430\u043b\u0438.",duration:"\u041b\u0443\u0447\u0448\u0435 \u0440\u0430\u0431\u043e\u0442\u0430\u044e\u0442 \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u0435 \u043f\u043e\u0434\u0445\u043e\u0434\u044b: \u043f\u0440\u0438\u043c\u0435\u0440\u043d\u043e 5\u201315 \u043c\u0438\u043d\u0443\u0442 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0440\u0430\u0437 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e. \u0421\u0447\u0438\u0442\u0430\u0439\u0442\u0435 \u0437\u0430 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442 \u0447\u0438\u0441\u043b\u043e \u043e\u0442\u043a\u0440\u044b\u0442\u0438\u0439 \u0438\u043b\u0438 \u0432\u0440\u0435\u043c\u044f \u043f\u0440\u043e\u0445\u043e\u0436\u0434\u0435\u043d\u0438\u044f \u0438 \u0443\u0432\u0435\u043b\u0438\u0447\u0438\u0432\u0430\u0439\u0442\u0435 \u0440\u0430\u0437\u043c\u0435\u0440 \u043f\u043e\u043b\u044f \u0442\u043e\u043b\u044c\u043a\u043e \u0442\u043e\u0433\u0434\u0430, \u043a\u043e\u0433\u0434\u0430 \u0442\u0435\u043a\u0443\u0449\u0438\u0439 \u0443\u0440\u043e\u0432\u0435\u043d\u044c \u0434\u0430\u0451\u0442\u0441\u044f \u043b\u0435\u0433\u043a\u043e, \u0430 \u043d\u0435 \u0447\u0430\u0441\u0430\u043c\u0438 \u0434\u043e\u043b\u0431\u0438\u0442\u0435 \u043e\u0434\u043d\u0443 \u0438 \u0442\u0443 \u0436\u0435 \u0440\u0430\u0441\u043a\u043b\u0430\u0434\u043a\u0443.",research:"\u0414\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u043d\u0435\u0435 \u0432\u0441\u0435\u0433\u043e \u0440\u043e\u0432\u043d\u043e \u0442\u043e, \u0447\u0435\u0433\u043e \u0438 \u0436\u0434\u0451\u0448\u044c: \u0432\u044b \u0437\u0430\u043c\u0435\u0442\u043d\u043e \u043b\u0443\u0447\u0448\u0435 \u0441\u043f\u0440\u0430\u0432\u043b\u044f\u0435\u0442\u0435\u0441\u044c \u0438\u043c\u0435\u043d\u043d\u043e \u0441 \u044d\u0442\u043e\u0439 \u0438\u0433\u0440\u043e\u0439 \u043d\u0430 \u043f\u043e\u0438\u0441\u043a \u043f\u0430\u0440 \u0438 \u0437\u0430\u043f\u043e\u043c\u0438\u043d\u0430\u043d\u0438\u0435\u043c \u043f\u043e\u0437\u0438\u0446\u0438\u0439 \u043a\u0430\u0440\u0442\u043e\u0447\u0435\u043a \u2014 \u044d\u0442\u043e \u0440\u0435\u0430\u043b\u044c\u043d\u044b\u0439 \xab\u0431\u043b\u0438\u0436\u043d\u0438\u0439 \u043f\u0435\u0440\u0435\u043d\u043e\u0441\xbb. \u0428\u0438\u0440\u043e\u043a\u0438\u0435 \u0437\u0430\u044f\u0432\u043b\u0435\u043d\u0438\u044f, \u0447\u0442\u043e \u0438\u0433\u0440\u0430 \u0443\u043b\u0443\u0447\u0448\u0430\u0435\u0442 \u043f\u0430\u043c\u044f\u0442\u044c \u0432\u043e\u043e\u0431\u0449\u0435, \u043f\u0440\u0435\u0434\u043e\u0442\u0432\u0440\u0430\u0449\u0430\u0435\u0442 \u0432\u043e\u0437\u0440\u0430\u0441\u0442\u043d\u043e\u0435 \u0441\u043d\u0438\u0436\u0435\u043d\u0438\u0435 \u0438\u043b\u0438 \u043f\u043e\u0432\u044b\u0448\u0430\u0435\u0442 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442, \u043a\u0443\u0434\u0430 \u0441\u043b\u0430\u0431\u0435\u0435: \u043a\u0440\u0443\u043f\u043d\u044b\u0435 \u043e\u0431\u0437\u043e\u0440\u044b \u043f\u043e\u043a\u0430\u0437\u044b\u0432\u0430\u044e\u0442, \u0447\u0442\u043e \u0438\u0433\u0440\u044b \u043d\u0430 \u0440\u0430\u0431\u043e\u0447\u0443\u044e \u043f\u0430\u043c\u044f\u0442\u044c \u0438 \xab\u0442\u0440\u0435\u043d\u0430\u0436\u0451\u0440\u044b \u043c\u043e\u0437\u0433\u0430\xbb \u0440\u0435\u0434\u043a\u043e \u0434\u0430\u044e\u0442 \xab\u0434\u0430\u043b\u044c\u043d\u0438\u0439 \u043f\u0435\u0440\u0435\u043d\u043e\u0441\xbb \u043d\u0430 \u043d\u0435\u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u043c\u044b\u0435 \u0441\u043f\u043e\u0441\u043e\u0431\u043d\u043e\u0441\u0442\u0438, \u0430 \u0433\u0440\u043e\u043c\u043a\u043e\u0435 \u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043d\u0438\u0435 \u043f\u0440\u043e \u0440\u043e\u0441\u0442 \u043f\u043e\u0434\u0432\u0438\u0436\u043d\u043e\u0433\u043e \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442\u0430 \u043d\u0435\u043e\u0434\u043d\u043e\u043a\u0440\u0430\u0442\u043d\u043e \u043d\u0435 \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0438\u043b\u043e\u0441\u044c \u0432 \u043f\u043e\u0432\u0442\u043e\u0440\u043d\u044b\u0445 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u044f\u0445 \u2014 \u0442\u0430\u043a \u0447\u0442\u043e \u043a \u0433\u0440\u043e\u043c\u043a\u0438\u043c \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f\u043c \u0441\u0442\u043e\u0438\u0442 \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u044c\u0441\u044f \u043e\u0441\u0442\u043e\u0440\u043e\u0436\u043d\u043e.",rec:"\u0418\u0433\u0440\u0430\u0439\u0442\u0435 \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u043c\u0438 \u0441\u043e\u0441\u0440\u0435\u0434\u043e\u0442\u043e\u0447\u0435\u043d\u043d\u044b\u043c\u0438 \u043f\u043e\u0434\u0445\u043e\u0434\u0430\u043c\u0438 \u0438 \u0441\u043e\u0440\u0435\u0432\u043d\u0443\u0439\u0442\u0435\u0441\u044c \u0441\u043e \u0441\u0432\u043e\u0438\u043c \u043b\u0443\u0447\u0448\u0438\u043c \u0447\u0438\u0441\u043b\u043e\u043c \u043e\u0442\u043a\u0440\u044b\u0442\u0438\u0439, \u0430 \u043d\u0435 \u0433\u043e\u043d\u0438\u0442\u0435\u0441\u044c \u0437\u0430 \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u0435\u043c \xab\u043f\u0440\u043e\u043a\u0430\u0447\u0430\u0442\u044c \u043c\u043e\u0437\u0433\xbb.",faq:[["\xab\u041f\u0430\u0440\u044b \u043a\u0430\u0440\u0442\u0438\u043d\u043e\u043a\xbb \u043f\u0440\u0430\u0432\u0434\u0430 \u0443\u043b\u0443\u0447\u0448\u0430\u044e\u0442 \u043f\u0430\u043c\u044f\u0442\u044c?","\u041e\u043d\u0438 \u043d\u0430\u0434\u0451\u0436\u043d\u043e \u0443\u043b\u0443\u0447\u0448\u0430\u044e\u0442 \u043f\u0430\u043c\u044f\u0442\u044c \u0438\u043c\u0435\u043d\u043d\u043e \u043f\u043e\u0434 \u044d\u0442\u0443 \u0437\u0430\u0434\u0430\u0447\u0443 \u2014 \u043f\u043e\u0438\u0441\u043a \u0438 \u043f\u0440\u0438\u043f\u043e\u043c\u0438\u043d\u0430\u043d\u0438\u0435 \u043f\u0430\u0440\u043d\u044b\u0445 \u043a\u0430\u0440\u0442\u043e\u0447\u0435\u043a. \u0410 \u0432\u043e\u0442 \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0438\u0442\u0441\u044f \u043b\u0438 \u044d\u0442\u043e \u043d\u0430 \u043f\u043e\u0432\u0441\u0435\u0434\u043d\u0435\u0432\u043d\u0443\u044e \u043f\u0430\u043c\u044f\u0442\u044c, \u0434\u043e\u043a\u0430\u0437\u0430\u043d\u043e \u0441\u043b\u0430\u0431\u043e; \u0447\u0435\u0441\u0442\u043d\u043e\u0435 \u043e\u0436\u0438\u0434\u0430\u043d\u0438\u0435 \u0442\u0430\u043a\u043e\u0435: \u0432\u044b \u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u0435\u0441\u044c \u043b\u0443\u0447\u0448\u0435 \u0432 \u0441\u0430\u043c\u043e\u0439 \u0438\u0433\u0440\u0435."],["\u041a\u0430\u043a \u0432\u044b\u0438\u0433\u0440\u044b\u0432\u0430\u0442\u044c \u0437\u0430 \u043c\u0435\u043d\u044c\u0448\u0435\u0435 \u0447\u0438\u0441\u043b\u043e \u0445\u043e\u0434\u043e\u0432?","\u041e\u0442\u043a\u0440\u044b\u0432\u0430\u0439\u0442\u0435 \u043a\u0430\u0440\u0442\u043e\u0447\u043a\u0438 \u0432 \u0444\u0438\u043a\u0441\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u043e\u043c \u043f\u043e\u0440\u044f\u0434\u043a\u0435, \u0447\u0442\u043e\u0431\u044b \u0432\u044b\u0441\u0442\u0440\u043e\u0438\u0442\u044c \u043c\u044b\u0441\u043b\u0435\u043d\u043d\u0443\u044e \u043a\u0430\u0440\u0442\u0443, \u043d\u0430\u0437\u044b\u0432\u0430\u0439\u0442\u0435 \u0438\u043b\u0438 \u043f\u0440\u0438\u0432\u044f\u0437\u044b\u0432\u0430\u0439\u0442\u0435 \u043a \u043c\u0435\u0441\u0442\u0443 \u043a\u0430\u0436\u0434\u043e\u0435 \u0438\u0437\u043e\u0431\u0440\u0430\u0436\u0435\u043d\u0438\u0435, \u0430 \u043a\u043e\u0433\u0434\u0430 \u043a\u0430\u0436\u0435\u0442\u0441\u044f, \u0447\u0442\u043e \u0437\u043d\u0430\u0435\u0442\u0435 \u043f\u0430\u0440\u0443, \u043f\u0435\u0440\u0432\u043e\u0439 \u043f\u0435\u0440\u0435\u0432\u043e\u0440\u0430\u0447\u0438\u0432\u0430\u0439\u0442\u0435 \u0442\u0443 \u043a\u0430\u0440\u0442\u043e\u0447\u043a\u0443, \u0432 \u043a\u043e\u0442\u043e\u0440\u043e\u0439 \u043d\u0435 \u0443\u0432\u0435\u0440\u0435\u043d\u044b \u2014 \u0442\u043e\u0433\u0434\u0430 \u043e\u0448\u0438\u0431\u043a\u0430 \u0445\u043e\u0442\u044f \u0431\u044b \u0447\u0442\u043e-\u0442\u043e \u043f\u043e\u0434\u0441\u043a\u0430\u0436\u0435\u0442, \u0430 \u043d\u0435 \u0441\u043e\u0436\u0436\u0451\u0442 \u0432\u0435\u0440\u043d\u0443\u044e \u043f\u0430\u0440\u0443."],["\u041a\u0430\u043a\u043e\u0433\u043e \u0440\u0430\u0437\u043c\u0435\u0440\u0430 \u0431\u0440\u0430\u0442\u044c \u043f\u043e\u043b\u0435?","\u041d\u0430\u0447\u043d\u0438\u0442\u0435 \u0441 \u0440\u0430\u0437\u043c\u0435\u0440\u0430, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u043f\u0440\u043e\u0445\u043e\u0434\u0438\u0442\u0435 \u0431\u0435\u0437 \u043d\u0430\u043f\u0440\u044f\u0436\u0435\u043d\u0438\u044f, \u0438 \u0443\u0432\u0435\u043b\u0438\u0447\u0438\u0432\u0430\u0439\u0442\u0435 \u0442\u043e\u043b\u044c\u043a\u043e \u043a\u043e\u0433\u0434\u0430 \u0441\u0442\u0430\u043d\u0435\u0442 \u043b\u0435\u0433\u043a\u043e. \u041f\u043e\u043b\u0435, \u0437\u0430\u043c\u0435\u0442\u043d\u043e \u043f\u0440\u0435\u0432\u044b\u0448\u0430\u044e\u0449\u0435\u0435 \u043e\u0431\u044a\u0451\u043c \u0432\u0430\u0448\u0435\u0439 \u043f\u0430\u043c\u044f\u0442\u0438, \u043f\u0440\u0435\u0432\u0440\u0430\u0449\u0430\u0435\u0442\u0441\u044f \u0432 \u0443\u0433\u0430\u0434\u0430\u0439\u043a\u0443 \u0438 \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u0441\u043a\u043e\u0440\u0435\u0435 \u0440\u0430\u0437\u0434\u0440\u0430\u0436\u0435\u043d\u0438\u0435, \u0447\u0435\u043c \u043f\u0430\u043c\u044f\u0442\u044c."]],variants:"\u0412\u0435\u0440\u0441\u0438\u0438 \u0440\u0430\u0437\u043b\u0438\u0447\u0430\u044e\u0442\u0441\u044f \u0440\u0430\u0437\u043c\u0435\u0440\u043e\u043c \u043f\u043e\u043b\u044f (\u043e\u0442 \u043b\u0451\u0433\u043a\u043e\u0433\u043e 4x4 \u0434\u043e \u0431\u043e\u043b\u044c\u0448\u0438\u0445 \u0440\u0430\u0441\u043a\u043b\u0430\u0434\u043e\u043a), \u0441\u043e\u0434\u0435\u0440\u0436\u0430\u043d\u0438\u0435\u043c (\u0436\u0438\u0432\u043e\u0442\u043d\u044b\u0435, \u0441\u0438\u043c\u0432\u043e\u043b\u044b, \u0447\u0438\u0441\u043b\u0430, \u0441\u043b\u043e\u0432\u0430 \u0438\u043b\u0438 \u043f\u0430\u0440\u044b \xab\u0441\u043b\u043e\u0432\u043e \u2014 \u043a\u0430\u0440\u0442\u0438\u043d\u043a\u0430\xbb \u0434\u043b\u044f \u043e\u0431\u0443\u0447\u0435\u043d\u0438\u044f) \u0438 \u043f\u0440\u0430\u0432\u0438\u043b\u0430\u043c\u0438: \u0438\u0433\u0440\u0430 \u043d\u0430 \u0432\u0440\u0435\u043c\u044f \u0438\u043b\u0438 \u0441 \u043b\u0438\u043c\u0438\u0442\u043e\u043c \u0445\u043e\u0434\u043e\u0432, \u0432 \u043e\u0434\u0438\u043d\u043e\u0447\u043a\u0443 \u043f\u0440\u043e\u0442\u0438\u0432 \u0441\u043e\u0431\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0433\u043e \u0440\u0435\u043a\u043e\u0440\u0434\u0430 \u0438\u043b\u0438 \u043f\u043e \u043e\u0447\u0435\u0440\u0435\u0434\u0438 \u0441 \u0434\u0440\u0443\u0433\u0438\u043c\u0438, \u0430 \u0442\u0430\u043a\u0436\u0435 \u0443\u0441\u043b\u043e\u0436\u043d\u0451\u043d\u043d\u044b\u0435 \u0440\u0435\u0436\u0438\u043c\u044b, \u0433\u0434\u0435 \u043a\u0430\u0440\u0442\u043e\u0447\u043a\u0438 \u043c\u0435\u043d\u044f\u044e\u0442\u0441\u044f \u043c\u0435\u0441\u0442\u0430\u043c\u0438 \u0438\u043b\u0438 \u0433\u0434\u0435 \u043d\u0443\u0436\u043d\u043e \u0441\u043e\u0431\u0440\u0430\u0442\u044c \u0442\u0440\u043e\u0439\u043a\u0443, \u0430 \u043d\u0435 \u043f\u0430\u0440\u0443."},en:{about:"Picture Pairs lays a grid of cards face down, each image appearing exactly twice. You flip two cards per turn: if they match, the pair stays open and is cleared; if not, they flip back and you try again, the goal being to clear the whole board in as few flips as possible.",benefit:"It mainly trains visual short-term and working memory \u2014 holding in mind where a card was and matching it to a card you see now. It also leans on sustained attention and a bit of spatial memory, since you are tracking positions on a grid.",history:"The matching-pairs idea is very old: the Japanese shell-matching game kai-awase dates back to the Heian period (roughly 8th to 12th century). As a card game it spread in the 20th century under many names \u2014 Pelmanism (recorded in Hoyle's Games Modernized, 1923), Concentration, Pairs and Pexeso \u2014 and was popularised in commercial form by Ravensburger's boxed game Memory in 1959.",creator:"There is no single inventor. It is a traditional public-domain game from the broad matching-pairs tradition, with an early shell-matching ancestor (kai-awase) in Heian-era Japan; the well-known boxed version Memory was published by Ravensburger in 1959, reportedly developed from a homemade family game rather than designed from scratch by one author.",methods:"Don't flip at random \u2014 work systematically, e.g. row by row, so each new card gives you the most information. Try to label cards verbally or by location as you uncover them ('robot top-left'), flip the card you're least sure about first to avoid wasting a known match, and keep the pace steady rather than rushing, since a single careless flip resets a pair you already knew.",duration:"Short sessions work best: about 5 to 15 minutes, a few times a week. Treat your flip count or completion time as the score to beat, and step up the grid size only once a level feels comfortable rather than grinding the same board for hours.",research:"Evidence is strongest for exactly what you'd expect \u2014 you get noticeably better at this matching task and at remembering card positions, which is genuine near transfer. Broad claims that it sharpens general memory, prevents age-related decline or raises intelligence are far weaker: large reviews find that working-memory and brain-training games rarely produce 'far transfer' to untrained abilities, and the headline claim that such training boosts fluid intelligence has repeatedly failed to replicate, so treat the grand promises with caution.",rec:"Play in short, focused bursts and compete against your own best flip count rather than chasing a promise of a 'better brain'.",faq:[["Does Picture Pairs actually improve my memory?","It reliably improves your memory for this kind of task \u2014 finding and recalling matching cards. Whether that carries over to everyday memory is not well supported; the honest expectation is that you get better at the game itself."],["What's a good strategy to win in fewer moves?","Uncover cards in a fixed order so you build a mental map, name or place-tag each image as you see it, and when you think you know a pair, flip the uncertain card first \u2014 that way a wrong guess still teaches you something instead of wasting a sure match."],["How big should the grid be?","Start with a size you can clear comfortably and only go bigger once it feels easy. A grid that is far beyond your memory span just becomes guesswork, which trains frustration more than memory."]],variants:"Versions vary by grid size (easy 4x4 up to large boards), by content (animals, symbols, numbers, words, or word-to-picture pairs for learning), and by rules \u2014 timed or move-limited play, single-player against your own record or turn-taking with others, and harder modes where cards shuffle positions or where you match a triplet instead of a pair."},es:{about:"Parejas de Im\xe1genes coloca una cuadr\xedcula de cartas boca abajo, donde cada imagen aparece exactamente dos veces. En cada turno volteas dos cartas: si coinciden, la pareja se queda destapada y se retira; si no, vuelven a darse la vuelta y lo intentas de nuevo, con el objetivo de despejar todo el tablero en la menor cantidad de volteos posible.",benefit:"Entrena sobre todo la memoria visual a corto plazo y la memoria de trabajo: retener en la mente d\xf3nde estaba una carta y emparejarla con otra que ves ahora. Tambi\xe9n se apoya en la atenci\xf3n sostenida y, en parte, en la memoria espacial, ya que vas siguiendo posiciones sobre una cuadr\xedcula.",history:"La idea de emparejar es muy antigua: el juego japon\xe9s de emparejar conchas kai-awase se remonta al per\xedodo Heian (aproximadamente del siglo VIII al XII). Como juego de cartas se difundi\xf3 en el siglo XX bajo muchos nombres \u2014Pelmanism (recogido en Hoyle's Games Modernized, 1923), Concentration, Pairs y Pexeso\u2014 y se populariz\xf3 en formato comercial con el juego de caja Memory de Ravensburger en 1959.",creator:"No tiene un \xfanico inventor. Es un juego tradicional de dominio p\xfablico dentro de la amplia tradici\xf3n de emparejar pares, con un antepasado temprano de emparejado de conchas (kai-awase) en el Jap\xf3n de la era Heian; la conocida versi\xf3n en caja, Memory, fue publicada por Ravensburger en 1959 y, seg\xfan se cuenta, surgi\xf3 a partir de un juego casero familiar m\xe1s que del dise\xf1o desde cero de un solo autor.",methods:"No voltees al azar: trabaja de forma sistem\xe1tica, por ejemplo fila por fila, para que cada carta nueva te d\xe9 la mayor informaci\xf3n posible. Intenta etiquetar las cartas verbalmente o por su ubicaci\xf3n a medida que las descubres ('robot arriba a la izquierda'), voltea primero la carta de la que menos seguro est\xe9s para no desperdiciar una pareja ya conocida, y mant\xe9n un ritmo constante en vez de apresurarte, porque un solo volteo descuidado reinicia una pareja que ya sab\xedas.",duration:"Las sesiones cortas funcionan mejor: unos 5 a 15 minutos, varias veces por semana. Toma tu n\xfamero de volteos o tu tiempo de finalizaci\xf3n como la marca a superar, y aumenta el tama\xf1o de la cuadr\xedcula solo cuando un nivel te resulte c\xf3modo, en lugar de repetir el mismo tablero durante horas.",research:"La evidencia es m\xe1s s\xf3lida justo en lo que cabr\xeda esperar: mejoras notablemente en esta tarea de emparejado y en recordar las posiciones de las cartas, lo que constituye una transferencia cercana genuina. Las afirmaciones amplias de que agudiza la memoria general, previene el deterioro asociado a la edad o eleva la inteligencia son mucho m\xe1s d\xe9biles: las grandes revisiones encuentran que los juegos de memoria de trabajo y de entrenamiento cerebral rara vez producen una 'transferencia lejana' a habilidades no entrenadas, y la afirmaci\xf3n estelar de que ese entrenamiento aumenta la inteligencia fluida ha fracasado en replicarse una y otra vez, as\xed que toma las grandes promesas con cautela.",rec:"Juega en r\xe1fagas cortas y concentradas y compite contra tu propio mejor n\xfamero de volteos, en lugar de perseguir la promesa de un 'cerebro mejor'.",faq:[["\xbfParejas de Im\xe1genes mejora de verdad mi memoria?","Mejora de forma fiable tu memoria para este tipo de tarea: encontrar y recordar cartas que coinciden. Que eso se traslade a la memoria del d\xeda a d\xeda no est\xe1 bien respaldado; la expectativa honesta es que mejoras en el propio juego."],["\xbfCu\xe1l es una buena estrategia para ganar con menos movimientos?","Descubre las cartas en un orden fijo para construir un mapa mental, nombra o etiqueta por ubicaci\xf3n cada imagen al verla, y cuando creas saber una pareja, voltea primero la carta dudosa: as\xed una conjetura equivocada igual te ense\xf1a algo en vez de desperdiciar una pareja segura."],["\xbfDe qu\xe9 tama\xf1o deber\xeda ser la cuadr\xedcula?","Empieza con un tama\xf1o que puedas despejar con comodidad y aumenta solo cuando te resulte f\xe1cil. Una cuadr\xedcula muy por encima de tu capacidad de memoria se convierte en pura adivinanza, lo que entrena m\xe1s la frustraci\xf3n que la memoria."]],variants:"Las versiones var\xedan por tama\xf1o de cuadr\xedcula (desde un sencillo 4x4 hasta tableros grandes), por contenido (animales, s\xedmbolos, n\xfameros, palabras o parejas palabra-imagen para aprender) y por reglas: partidas cronometradas o con l\xedmite de movimientos, un jugador contra su propio r\xe9cord o por turnos con otros, y modos m\xe1s dif\xedciles donde las cartas cambian de posici\xf3n o donde emparejas un tr\xedo en lugar de una pareja."},de:{about:"Bei Picture Pairs liegt ein Raster aus verdeckten Karten vor dir, wobei jedes Bild genau zweimal vorkommt. Pro Zug deckst du zwei Karten auf: Stimmen sie \xfcberein, bleibt das Paar offen liegen und wird entfernt; wenn nicht, werden sie wieder umgedreht und du versuchst es erneut. Ziel ist es, das gesamte Feld mit so wenigen Aufdeckungen wie m\xf6glich abzur\xe4umen.",benefit:"Trainiert wird vor allem das visuelle Kurzzeit- und Arbeitsged\xe4chtnis \u2013 sich zu merken, wo eine Karte lag, und sie mit einer Karte abzugleichen, die du gerade siehst. Zus\xe4tzlich werden die anhaltende Aufmerksamkeit und etwas r\xe4umliches Ged\xe4chtnis beansprucht, da du die Positionen auf dem Raster im Blick behalten musst.",history:"Die Idee des Paarefindens ist sehr alt: Das japanische Muschelspiel kai-awase reicht bis in die Heian-Zeit zur\xfcck (etwa 8. bis 12. Jahrhundert). Als Kartenspiel verbreitete es sich im 20. Jahrhundert unter vielen Namen \u2013 Pelmanism (festgehalten in Hoyle's Games Modernized, 1923), Concentration, Pairs und Pexeso \u2013 und wurde in kommerzieller Form durch Ravensburgers Schachtelspiel Memory ab 1959 popul\xe4r.",creator:"Es gibt keinen einzelnen Erfinder. Es handelt sich um ein gemeinfreies Traditionsspiel aus der breiten Tradition des Paarefindens, mit einem fr\xfchen Vorl\xe4ufer im Muschelspiel kai-awase im Japan der Heian-Zeit; die bekannte Schachtelversion Memory wurde 1959 von Ravensburger ver\xf6ffentlicht und ging Berichten zufolge aus einem selbstgemachten Familienspiel hervor, statt von einem einzelnen Urheber von Grund auf entworfen worden zu sein.",methods:"Decke nicht wahllos auf, sondern arbeite systematisch, etwa Reihe f\xfcr Reihe, damit dir jede neue Karte m\xf6glichst viel Information liefert. Versuche, die Karten beim Aufdecken sprachlich oder \xfcber ihren Ort zu benennen ('Roboter oben links'), decke bei einem vermuteten Paar zuerst die Karte auf, bei der du am unsichersten bist, um kein bekanntes Paar zu verschenken, und halte ein gleichm\xe4\xdfiges Tempo, statt zu hetzen \u2013 denn eine einzige unbedachte Aufdeckung macht ein Paar zunichte, das du schon kanntest.",duration:"Kurze Einheiten funktionieren am besten: etwa 5 bis 15 Minuten, ein paar Mal pro Woche. Nimm deine Anzahl an Aufdeckungen oder deine Bestzeit als zu schlagenden Wert und vergr\xf6\xdfere das Raster erst dann, wenn sich eine Stufe komfortabel anf\xfchlt, statt dasselbe Feld stundenlang durchzukauen.",research:"Am st\xe4rksten ist die Beleglage genau f\xfcr das, was man erwarten w\xfcrde \u2013 du wirst in dieser Zuordnungsaufgabe und im Merken von Kartenpositionen sp\xfcrbar besser, was echter Nahtransfer ist. Weitreichende Behauptungen, es sch\xe4rfe das Ged\xe4chtnis allgemein, beuge altersbedingtem Abbau vor oder steigere die Intelligenz, sind weitaus schw\xe4cher belegt: Gro\xdfe \xdcbersichtsarbeiten zeigen, dass Arbeitsged\xe4chtnis- und Gehirntrainingsspiele nur selten 'Ferntransfer' auf untrainierte F\xe4higkeiten erzeugen, und die plakative Behauptung, solches Training steigere die fluide Intelligenz, lie\xdf sich wiederholt nicht replizieren \u2013 nimm die gro\xdfen Versprechen also mit Vorsicht.",rec:"Spiele in kurzen, konzentrierten Sch\xfcben und tritt gegen deine eigene Bestmarke an Aufdeckungen an, statt einem Versprechen von einem 'besseren Gehirn' hinterherzujagen.",faq:[["Verbessert Picture Pairs tats\xe4chlich mein Ged\xe4chtnis?","Es verbessert zuverl\xe4ssig dein Ged\xe4chtnis f\xfcr genau diese Art von Aufgabe \u2013 das Finden und Erinnern passender Karten. Ob sich das auf das Alltagsged\xe4chtnis \xfcbertr\xe4gt, ist nicht gut belegt; die ehrliche Erwartung ist, dass du im Spiel selbst besser wirst."],["Was ist eine gute Strategie, um mit weniger Z\xfcgen zu gewinnen?","Decke die Karten in einer festen Reihenfolge auf, um dir eine mentale Karte aufzubauen, benenne jedes Bild oder versieh es mit einer Ortsmarke, sobald du es siehst, und wenn du ein Paar zu kennen glaubst, decke zuerst die unsichere Karte auf \u2013 so bringt dir selbst eine falsche Vermutung noch etwas, statt ein sicheres Paar zu verschenken."],["Wie gro\xdf sollte das Raster sein?","Beginne mit einer Gr\xf6\xdfe, die du komfortabel abr\xe4umen kannst, und gehe erst dann gr\xf6\xdfer, wenn es sich leicht anf\xfchlt. Ein Raster, das deine Merkspanne weit \xfcbersteigt, wird zum reinen Raten, was eher Frust als Ged\xe4chtnis trainiert."]],variants:"Die Versionen unterscheiden sich nach Rastergr\xf6\xdfe (leicht 4x4 bis hin zu gro\xdfen Feldern), nach Inhalt (Tiere, Symbole, Zahlen, W\xf6rter oder Wort-Bild-Paare zum Lernen) und nach Regeln \u2013 Spiel auf Zeit oder mit Zuglimit, allein gegen den eigenen Rekord oder abwechselnd mit anderen, sowie schwerere Modi, bei denen Karten ihre Positionen tauschen oder bei denen du ein Tripel statt eines Paares finden musst."},pt:{about:"O Jogo dos Pares disp\xf5e uma grade de cartas viradas para baixo, com cada imagem aparecendo exatamente duas vezes. A cada jogada voc\xea vira duas cartas: se forem iguais, o par fica aberto e \xe9 retirado; se n\xe3o, voltam a virar e voc\xea tenta de novo, com o objetivo de limpar o tabuleiro inteiro no menor n\xfamero de viradas poss\xedvel.",benefit:"Ele treina sobretudo a mem\xf3ria visual de curto prazo e a mem\xf3ria de trabalho \u2014 guardar na cabe\xe7a onde estava uma carta e associ\xe1-la a outra que voc\xea v\xea agora. Tamb\xe9m exige aten\xe7\xe3o sustentada e um pouco de mem\xf3ria espacial, j\xe1 que voc\xea est\xe1 acompanhando posi\xe7\xf5es numa grade.",history:"A ideia de combinar pares \xe9 muito antiga: o jogo japon\xeas de pareamento de conchas kai-awase remonta ao per\xedodo Heian (aproximadamente do s\xe9culo VIII ao XII). Como jogo de cartas, espalhou-se no s\xe9culo XX sob muitos nomes \u2014 Pelmanism (registrado em Hoyle's Games Modernized, 1923), Concentra\xe7\xe3o, Pares e Pexeso \u2014 e foi popularizado em forma comercial pelo jogo de caixa Memory, da Ravensburger, em 1959.",creator:"N\xe3o h\xe1 um \xfanico inventor. \xc9 um jogo tradicional de dom\xednio p\xfablico, vindo da ampla tradi\xe7\xe3o de pareamento de pares, com um ancestral antigo de pareamento de conchas (kai-awase) no Jap\xe3o da era Heian; a conhecida vers\xe3o em caixa Memory foi publicada pela Ravensburger em 1959, segundo relatos desenvolvida a partir de um jogo caseiro de fam\xedlia, e n\xe3o criada do zero por um \xfanico autor.",methods:"N\xe3o vire cartas ao acaso \u2014 trabalhe de forma sistem\xe1tica, por exemplo fileira por fileira, para que cada carta nova lhe d\xea o m\xe1ximo de informa\xe7\xe3o. Procure rotular as cartas verbalmente ou pela posi\xe7\xe3o \xe0 medida que as descobre ('rob\xf4 no canto superior esquerdo'), vire primeiro a carta sobre a qual voc\xea tem mais d\xfavida para n\xe3o desperdi\xe7ar um par j\xe1 conhecido, e mantenha um ritmo constante em vez de se apressar, porque uma \xfanica virada descuidada zera um par que voc\xea j\xe1 sabia.",duration:"Sess\xf5es curtas funcionam melhor: cerca de 5 a 15 minutos, algumas vezes por semana. Trate o n\xfamero de viradas ou o tempo de conclus\xe3o como a marca a ser batida, e s\xf3 aumente o tamanho da grade quando um n\xedvel j\xe1 estiver confort\xe1vel, em vez de moer o mesmo tabuleiro por horas.",research:"As evid\xeancias s\xe3o mais fortes exatamente para o que se espera \u2014 voc\xea fica visivelmente melhor nessa tarefa de pareamento e em lembrar posi\xe7\xf5es de cartas, o que \xe9 uma transfer\xeancia pr\xf3xima genu\xedna. Afirma\xe7\xf5es amplas de que ele agu\xe7a a mem\xf3ria geral, previne o decl\xednio ligado \xe0 idade ou eleva a intelig\xeancia s\xe3o bem mais fr\xe1geis: grandes revis\xf5es mostram que jogos de mem\xf3ria de trabalho e treino cerebral raramente produzem 'transfer\xeancia distante' para habilidades n\xe3o treinadas, e a alega\xe7\xe3o de destaque de que esse treino aumenta a intelig\xeancia fluida fracassou repetidamente em ser replicada, ent\xe3o encare as grandes promessas com cautela.",rec:"Jogue em sess\xf5es curtas e concentradas e compita contra o seu pr\xf3prio melhor n\xfamero de viradas, em vez de perseguir a promessa de um 'c\xe9rebro melhor'.",faq:[["O Jogo dos Pares realmente melhora a minha mem\xf3ria?","Ele melhora de forma confi\xe1vel a sua mem\xf3ria para esse tipo de tarefa \u2014 encontrar e recordar cartas iguais. Se isso se transfere para a mem\xf3ria do dia a dia n\xe3o tem bom respaldo; a expectativa honesta \xe9 que voc\xea fique melhor no pr\xf3prio jogo."],["Qual \xe9 uma boa estrat\xe9gia para vencer em menos jogadas?","Descubra as cartas numa ordem fixa para construir um mapa mental, d\xea um nome ou marque a posi\xe7\xe3o de cada imagem ao v\xea-la e, quando achar que conhece um par, vire primeiro a carta incerta \u2014 assim um palpite errado ainda lhe ensina algo, em vez de desperdi\xe7ar um par certo."],["Qual deve ser o tamanho da grade?","Comece com um tamanho que voc\xea consiga limpar com tranquilidade e s\xf3 aumente quando ficar f\xe1cil. Uma grade muito al\xe9m da sua capacidade de mem\xf3ria vira pura adivinha\xe7\xe3o, o que treina mais a frustra\xe7\xe3o do que a mem\xf3ria."]],variants:"As vers\xf5es variam pelo tamanho da grade (f\xe1cil 4x4 at\xe9 tabuleiros grandes), pelo conte\xfado (animais, s\xedmbolos, n\xfameros, palavras ou pares palavra-imagem para aprendizado) e pelas regras \u2014 jogo cronometrado ou com limite de jogadas, modo solo contra o pr\xf3prio recorde ou em turnos com outras pessoas, e modos mais dif\xedceis em que as cartas embaralham de posi\xe7\xe3o ou em que voc\xea forma um trio em vez de um par."},hi:{about:"Picture Pairs \u092e\u0947\u0902 \u0915\u093e\u0930\u094d\u0921\u094b\u0902 \u0915\u094b \u090f\u0915 \u0917\u094d\u0930\u093f\u0921 \u092e\u0947\u0902 \u0909\u0932\u094d\u091f\u093e \u092c\u093f\u091b\u093e\u092f\u093e \u091c\u093e\u0924\u093e \u0939\u0948, \u0914\u0930 \u0939\u0930 \u0924\u0938\u094d\u0935\u0940\u0930 \u0920\u0940\u0915 \u0926\u094b \u092c\u093e\u0930 \u0906\u0924\u0940 \u0939\u0948\u0964 \u0939\u0930 \u092c\u093e\u0930\u0940 \u092e\u0947\u0902 \u0906\u092a \u0926\u094b \u0915\u093e\u0930\u094d\u0921 \u092a\u0932\u091f\u0924\u0947 \u0939\u0948\u0902: \u0905\u0917\u0930 \u0935\u0947 \u0906\u092a\u0938 \u092e\u0947\u0902 \u092e\u0947\u0932 \u0916\u093e\u0924\u0947 \u0939\u0948\u0902 \u0924\u094b \u0935\u0939 \u091c\u094b\u0921\u093c\u0940 \u0916\u0941\u0932\u0940 \u0930\u0939\u0915\u0930 \u0939\u091f \u091c\u093e\u0924\u0940 \u0939\u0948; \u0905\u0917\u0930 \u0928\u0939\u0940\u0902, \u0924\u094b \u0935\u0947 \u092b\u093f\u0930 \u0938\u0947 \u0909\u0932\u094d\u091f\u0947 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902 \u0914\u0930 \u0906\u092a \u0926\u094b\u092c\u093e\u0930\u093e \u0915\u094b\u0936\u093f\u0936 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902\u0964 \u092e\u0915\u0938\u0926 \u0939\u0948 \u092a\u0942\u0930\u0947 \u092c\u094b\u0930\u094d\u0921 \u0915\u094b \u091c\u093f\u0924\u0928\u0947 \u0915\u092e \u092a\u0932\u091f\u093e\u0935\u094b\u0902 \u092e\u0947\u0902 \u0939\u094b \u0938\u0915\u0947 \u0938\u093e\u092b\u093c \u0915\u0930\u0928\u093e\u0964",benefit:"\u092f\u0939 \u092e\u0941\u0916\u094d\u092f \u0930\u0942\u092a \u0938\u0947 \u0926\u0943\u0936\u094d\u092f \u0905\u0932\u094d\u092a\u0915\u093e\u0932\u093f\u0915 \u0914\u0930 \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932 \u0938\u094d\u092e\u0943\u0924\u093f \u0915\u094b \u0938\u0927\u093e\u0924\u093e \u0939\u0948 \u2014 \u092f\u0939 \u092f\u093e\u0926 \u0930\u0916\u0928\u093e \u0915\u093f \u0915\u094b\u0908 \u0915\u093e\u0930\u094d\u0921 \u0915\u0939\u093e\u0901 \u0925\u093e \u0914\u0930 \u0909\u0938\u0947 \u0905\u092d\u0940 \u0926\u093f\u0916 \u0930\u0939\u0947 \u0915\u093e\u0930\u094d\u0921 \u0938\u0947 \u092e\u093f\u0932\u093e\u0928\u093e\u0964 \u0938\u093e\u0925 \u0939\u0940 \u092f\u0939 \u0928\u093f\u0930\u0902\u0924\u0930 \u0927\u094d\u092f\u093e\u0928 \u0914\u0930 \u0925\u094b\u0921\u093c\u0940-\u092c\u0939\u0941\u0924 \u0938\u094d\u0925\u093e\u0928\u093f\u0915 \u0938\u094d\u092e\u0943\u0924\u093f \u092a\u0930 \u092d\u0940 \u091f\u093f\u0915\u093e \u0939\u0948, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u0906\u092a \u0917\u094d\u0930\u093f\u0921 \u092a\u0930 \u091c\u0917\u0939\u094b\u0902 \u0915\u094b \u091f\u094d\u0930\u0948\u0915 \u0915\u0930 \u0930\u0939\u0947 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902\u0964",history:"\u092e\u0947\u0932-\u091c\u094b\u0921\u093c\u0940 \u0915\u093e \u0935\u093f\u091a\u093e\u0930 \u092c\u0939\u0941\u0924 \u092a\u0941\u0930\u093e\u0928\u093e \u0939\u0948: \u091c\u093e\u092a\u093e\u0928\u0940 \u0938\u0940\u092a-\u092e\u093f\u0932\u093e\u0928 \u0915\u093e \u0916\u0947\u0932 kai-awase \u0939\u0947\u0907\u0906\u0928 \u0915\u093e\u0932 (\u0932\u0917\u092d\u0917 8\u0935\u0940\u0902 \u0938\u0947 12\u0935\u0940\u0902 \u0938\u0926\u0940) \u0924\u0915 \u091c\u093e\u0924\u093e \u0939\u0948\u0964 \u0924\u093e\u0936 \u0915\u0947 \u0916\u0947\u0932 \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u092f\u0939 20\u0935\u0940\u0902 \u0938\u0926\u0940 \u092e\u0947\u0902 \u0915\u0908 \u0928\u093e\u092e\u094b\u0902 \u0938\u0947 \u092b\u0948\u0932\u093e \u2014 Pelmanism (Hoyle's Games Modernized, 1923 \u092e\u0947\u0902 \u0926\u0930\u094d\u091c), Concentration, Pairs \u0914\u0930 Pexeso \u2014 \u0914\u0930 \u0935\u094d\u092f\u093e\u0935\u0938\u093e\u092f\u093f\u0915 \u0930\u0942\u092a \u092e\u0947\u0902 \u0907\u0938\u0947 1959 \u092e\u0947\u0902 Ravensburger \u0915\u0947 \u0921\u093f\u092c\u094d\u092c\u093e\u092c\u0902\u0926 \u0916\u0947\u0932 Memory \u0928\u0947 \u0932\u094b\u0915\u092a\u094d\u0930\u093f\u092f \u092c\u0928\u093e\u092f\u093e\u0964",creator:"\u0907\u0938\u0915\u093e \u0915\u094b\u0908 \u090f\u0915 \u0906\u0935\u093f\u0937\u094d\u0915\u093e\u0930\u0915 \u0928\u0939\u0940\u0902 \u0939\u0948\u0964 \u092f\u0939 \u092e\u0947\u0932-\u091c\u094b\u0921\u093c\u0940 \u0915\u0940 \u0935\u094d\u092f\u093e\u092a\u0915 \u092a\u0930\u0902\u092a\u0930\u093e \u0938\u0947 \u0928\u093f\u0915\u0932\u093e \u090f\u0915 \u092a\u093e\u0930\u0902\u092a\u0930\u093f\u0915, \u0938\u093e\u0930\u094d\u0935\u091c\u0928\u093f\u0915-\u0921\u094b\u092e\u0947\u0928 \u0915\u093e \u0916\u0947\u0932 \u0939\u0948, \u091c\u093f\u0938\u0915\u093e \u090f\u0915 \u0906\u0930\u0902\u092d\u093f\u0915 \u0938\u0940\u092a-\u092e\u093f\u0932\u093e\u0928 \u092a\u0942\u0930\u094d\u0935\u091c (kai-awase) \u0939\u0947\u0907\u0906\u0928-\u0915\u093e\u0932\u0940\u0928 \u091c\u093e\u092a\u093e\u0928 \u092e\u0947\u0902 \u092e\u093f\u0932\u0924\u093e \u0939\u0948; \u091c\u093e\u0928\u093e-\u092a\u0939\u091a\u093e\u0928\u093e \u0921\u093f\u092c\u094d\u092c\u093e\u092c\u0902\u0926 \u0938\u0902\u0938\u094d\u0915\u0930\u0923 Memory 1959 \u092e\u0947\u0902 Ravensburger \u0928\u0947 \u092a\u094d\u0930\u0915\u093e\u0936\u093f\u0924 \u0915\u093f\u092f\u093e, \u0914\u0930 \u0915\u0939\u093e \u091c\u093e\u0924\u093e \u0939\u0948 \u0915\u093f \u092f\u0939 \u0915\u093f\u0938\u0940 \u090f\u0915 \u0932\u0947\u0916\u0915 \u0926\u094d\u0935\u093e\u0930\u093e \u0936\u0942\u0928\u094d\u092f \u0938\u0947 \u0921\u093f\u091c\u093c\u093e\u0907\u0928 \u0915\u093f\u090f \u091c\u093e\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u090f\u0915 \u0918\u0930\u0947\u0932\u0942 \u092a\u093e\u0930\u093f\u0935\u093e\u0930\u093f\u0915 \u0916\u0947\u0932 \u0938\u0947 \u0935\u093f\u0915\u0938\u093f\u0924 \u0939\u0941\u0906 \u0925\u093e\u0964",methods:"\u092c\u0947\u0924\u0930\u0924\u0940\u092c \u092e\u0924 \u092a\u0932\u091f\u093f\u090f \u2014 \u0935\u094d\u092f\u0935\u0938\u094d\u0925\u093f\u0924 \u0922\u0902\u0917 \u0938\u0947 \u091a\u0932\u093f\u090f, \u091c\u0948\u0938\u0947 \u092a\u0902\u0915\u094d\u0924\u093f-\u0926\u0930-\u092a\u0902\u0915\u094d\u0924\u093f, \u0924\u093e\u0915\u093f \u0939\u0930 \u0928\u092f\u093e \u0915\u093e\u0930\u094d\u0921 \u0906\u092a\u0915\u094b \u091c\u093c\u094d\u092f\u093e\u0926\u093e-\u0938\u0947-\u091c\u093c\u094d\u092f\u093e\u0926\u093e \u091c\u093e\u0928\u0915\u093e\u0930\u0940 \u0926\u0947\u0964 \u091c\u0948\u0938\u0947-\u091c\u0948\u0938\u0947 \u0915\u093e\u0930\u094d\u0921 \u0916\u0941\u0932\u0947\u0902, \u0909\u0928\u094d\u0939\u0947\u0902 \u0936\u092c\u094d\u0926\u094b\u0902 \u092e\u0947\u0902 \u092f\u093e \u091c\u0917\u0939 \u0915\u0947 \u0939\u093f\u0938\u093e\u092c \u0938\u0947 \u0928\u093e\u092e \u0926\u0947\u0928\u0947 \u0915\u0940 \u0915\u094b\u0936\u093f\u0936 \u0915\u0940\u091c\u093f\u090f ('\u0930\u094b\u092c\u094b\u091f \u090a\u092a\u0930-\u092c\u093e\u090f\u0901')\u0964 \u091c\u093f\u0938 \u0915\u093e\u0930\u094d\u0921 \u0915\u0947 \u092c\u093e\u0930\u0947 \u092e\u0947\u0902 \u0906\u092a \u0938\u092c\u0938\u0947 \u0915\u092e \u092a\u0915\u094d\u0915\u0947 \u0939\u094b\u0902, \u0909\u0938\u0947 \u092a\u0939\u0932\u0947 \u092a\u0932\u091f\u093f\u090f \u0924\u093e\u0915\u093f \u0915\u094b\u0908 \u091c\u093e\u0928\u0940-\u092a\u0939\u091a\u093e\u0928\u0940 \u091c\u094b\u0921\u093c\u0940 \u092c\u0930\u094d\u092c\u093e\u0926 \u0928 \u0939\u094b, \u0914\u0930 \u091c\u0932\u094d\u0926\u092c\u093e\u091c\u093c\u0940 \u0915\u0947 \u092c\u091c\u093e\u092f \u0930\u092b\u093c\u094d\u0924\u093e\u0930 \u0938\u094d\u0925\u093f\u0930 \u0930\u0916\u093f\u090f, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u090f\u0915 \u0932\u093e\u092a\u0930\u0935\u093e\u0939 \u092a\u0932\u091f\u093e\u0935 \u092a\u0939\u0932\u0947 \u0938\u0947 \u091c\u093e\u0928\u0940 \u0939\u0941\u0908 \u091c\u094b\u0921\u093c\u0940 \u0915\u094b \u092b\u093f\u0930 \u0938\u0947 \u0930\u0940\u0938\u0947\u091f \u0915\u0930 \u0926\u0947\u0924\u093e \u0939\u0948\u0964",duration:"\u091b\u094b\u091f\u0947 \u0938\u0924\u094d\u0930 \u0938\u092c\u0938\u0947 \u0905\u091a\u094d\u091b\u0947 \u0930\u0939\u0924\u0947 \u0939\u0948\u0902: \u0932\u0917\u092d\u0917 5 \u0938\u0947 15 \u092e\u093f\u0928\u091f, \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u0915\u0941\u091b \u092c\u093e\u0930\u0964 \u0905\u092a\u0928\u0947 \u092a\u0932\u091f\u093e\u0935\u094b\u0902 \u0915\u0940 \u0938\u0902\u0916\u094d\u092f\u093e \u092f\u093e \u092a\u0942\u0930\u093e \u0915\u0930\u0928\u0947 \u0915\u0947 \u0938\u092e\u092f \u0915\u094b \u0935\u0939 \u0938\u094d\u0915\u094b\u0930 \u092e\u093e\u0928\u093f\u090f \u091c\u093f\u0938\u0947 \u0939\u0930\u093e\u0928\u093e \u0939\u0948, \u0914\u0930 \u0917\u094d\u0930\u093f\u0921 \u0915\u093e \u0906\u0915\u093e\u0930 \u0924\u092d\u0940 \u092c\u0922\u093c\u093e\u0907\u090f \u091c\u092c \u0915\u094b\u0908 \u0938\u094d\u0924\u0930 \u0938\u0939\u091c \u0932\u0917\u0928\u0947 \u0932\u0917\u0947 \u2014 \u090f\u0915 \u0939\u0940 \u092c\u094b\u0930\u094d\u0921 \u0915\u094b \u0918\u0902\u091f\u094b\u0902 \u0930\u0917\u0921\u093c\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f\u0964",research:"\u0938\u092c\u0938\u0947 \u092a\u0941\u0916\u093c\u094d\u0924\u093e \u0938\u092c\u0942\u0924 \u0920\u0940\u0915 \u0909\u0938\u0940 \u092c\u093e\u0924 \u0915\u0947 \u0932\u093f\u090f \u0939\u0948 \u091c\u093f\u0938\u0915\u0940 \u0906\u092a \u0909\u092e\u094d\u092e\u0940\u0926 \u0915\u0930\u0947\u0902\u0917\u0947 \u2014 \u0906\u092a \u0907\u0938 \u092e\u093f\u0932\u093e\u0928-\u0915\u093e\u0930\u094d\u092f \u092e\u0947\u0902 \u0914\u0930 \u0915\u093e\u0930\u094d\u0921\u094b\u0902 \u0915\u0940 \u091c\u0917\u0939 \u092f\u093e\u0926 \u0930\u0916\u0928\u0947 \u092e\u0947\u0902 \u0938\u093e\u092b\u093c \u0924\u094c\u0930 \u092a\u0930 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902, \u091c\u094b \u0905\u0938\u0932\u0940 '\u0928\u091c\u093c\u0926\u0940\u0915\u0940 \u091f\u094d\u0930\u093e\u0902\u0938\u092b\u093c\u0930' \u0939\u0948\u0964 \u092f\u0947 \u092c\u0921\u093c\u0947-\u092c\u0921\u093c\u0947 \u0926\u093e\u0935\u0947 \u0915\u093f \u092f\u0939 \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u0938\u094d\u092e\u0943\u0924\u093f \u0924\u0947\u091c\u093c \u0915\u0930\u0924\u093e \u0939\u0948, \u0909\u092e\u094d\u0930 \u0915\u0947 \u0938\u093e\u0925 \u0906\u0928\u0947 \u0935\u093e\u0932\u0940 \u0917\u093f\u0930\u093e\u0935\u091f \u0930\u094b\u0915\u0924\u093e \u0939\u0948 \u092f\u093e \u092c\u0941\u0926\u094d\u0927\u093f \u092c\u0922\u093c\u093e\u0924\u093e \u0939\u0948, \u0915\u0939\u0940\u0902 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0915\u092e\u091c\u093c\u094b\u0930 \u0939\u0948\u0902: \u092c\u0921\u093c\u0947 \u0938\u092e\u0940\u0915\u094d\u0937\u093e \u0905\u0927\u094d\u092f\u092f\u0928 \u092a\u093e\u0924\u0947 \u0939\u0948\u0902 \u0915\u093f \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932-\u0938\u094d\u092e\u0943\u0924\u093f \u0914\u0930 \u0926\u093f\u092e\u093e\u0917\u0940-\u0915\u0938\u0930\u0924 \u0915\u0947 \u0916\u0947\u0932 \u0936\u093e\u092f\u0926 \u0939\u0940 \u0915\u092d\u0940 \u092c\u093f\u0928\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0935\u093e\u0932\u0940 \u0915\u094d\u0937\u092e\u0924\u093e\u0913\u0902 \u0924\u0915 '\u0926\u0942\u0930\u0917\u093e\u092e\u0940 \u091f\u094d\u0930\u093e\u0902\u0938\u092b\u093c\u0930' \u0926\u0947\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u092f\u0939 \u0938\u0941\u0930\u094d\u0916\u093f\u092f\u094b\u0902 \u0935\u093e\u0932\u093e \u0926\u093e\u0935\u093e \u0915\u093f \u0910\u0938\u0940 \u091f\u094d\u0930\u0947\u0928\u093f\u0902\u0917 \u0924\u0930\u0932 \u092c\u0941\u0926\u094d\u0927\u093f \u092c\u0922\u093c\u093e\u0924\u0940 \u0939\u0948, \u092c\u093e\u0930-\u092c\u093e\u0930 \u0926\u094b\u0939\u0930\u093e\u0928\u0947 \u092a\u0930 \u091f\u093f\u0915 \u0928\u0939\u0940\u0902 \u092a\u093e\u092f\u093e, \u0907\u0938\u0932\u093f\u090f \u092c\u0921\u093c\u0947-\u092c\u0921\u093c\u0947 \u0935\u093e\u0926\u094b\u0902 \u0915\u094b \u0938\u093e\u0935\u0927\u093e\u0928\u0940 \u0938\u0947 \u0932\u0940\u091c\u093f\u090f\u0964",rec:"'\u092c\u0947\u0939\u0924\u0930 \u0926\u093f\u092e\u093e\u0917' \u0915\u0947 \u0935\u093e\u0926\u0947 \u0915\u0947 \u092a\u0940\u091b\u0947 \u092d\u093e\u0917\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u091b\u094b\u091f\u0947, \u090f\u0915\u093e\u0917\u094d\u0930 \u0926\u094c\u0930\u094b\u0902 \u092e\u0947\u0902 \u0916\u0947\u0932\u093f\u090f \u0914\u0930 \u0905\u092a\u0928\u0947 \u0939\u0940 \u0938\u092c\u0938\u0947 \u0905\u091a\u094d\u091b\u0947 \u092a\u0932\u091f\u093e\u0935-\u0938\u094d\u0915\u094b\u0930 \u0938\u0947 \u092e\u0941\u0915\u093c\u093e\u092c\u0932\u093e \u0915\u0940\u091c\u093f\u090f\u0964",faq:[["\u0915\u094d\u092f\u093e Picture Pairs \u0938\u091a\u092e\u0941\u091a \u092e\u0947\u0930\u0940 \u092f\u093e\u0926\u0926\u093e\u0936\u094d\u0924 \u0938\u0941\u0927\u093e\u0930\u0924\u093e \u0939\u0948?","\u092f\u0939 \u0907\u0938 \u0924\u0930\u0939 \u0915\u0947 \u0915\u093e\u092e \u0915\u0947 \u0932\u093f\u090f \u2014 \u092e\u0947\u0932 \u0916\u093e\u0924\u0947 \u0915\u093e\u0930\u094d\u0921 \u0922\u0942\u0901\u0922\u0928\u0947 \u0914\u0930 \u092f\u093e\u0926 \u0930\u0916\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u2014 \u0906\u092a\u0915\u0940 \u092f\u093e\u0926\u0926\u093e\u0936\u094d\u0924 \u0915\u094b \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0922\u0902\u0917 \u0938\u0947 \u0938\u0941\u0927\u093e\u0930\u0924\u093e \u0939\u0948\u0964 \u092f\u0939 \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0940 \u092f\u093e\u0926\u0926\u093e\u0936\u094d\u0924 \u0924\u0915 \u092a\u0939\u0941\u0901\u091a\u0924\u093e \u0939\u0948 \u092f\u093e \u0928\u0939\u0940\u0902, \u0907\u0938\u0915\u093e \u0915\u094b\u0908 \u092e\u091c\u093c\u092c\u0942\u0924 \u0906\u0927\u093e\u0930 \u0928\u0939\u0940\u0902 \u0939\u0948; \u0908\u092e\u093e\u0928\u0926\u093e\u0930 \u0909\u092e\u094d\u092e\u0940\u0926 \u092f\u0939\u0940 \u0939\u0948 \u0915\u093f \u0906\u092a \u0916\u093c\u0941\u0926 \u0907\u0938 \u0916\u0947\u0932 \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902\u0964"],["\u0915\u092e \u091a\u093e\u0932\u094b\u0902 \u092e\u0947\u0902 \u091c\u0940\u0924\u0928\u0947 \u0915\u0940 \u0905\u091a\u094d\u091b\u0940 \u0930\u0923\u0928\u0940\u0924\u093f \u0915\u094d\u092f\u093e \u0939\u0948?","\u0915\u093e\u0930\u094d\u0921\u094b\u0902 \u0915\u094b \u090f\u0915 \u0924\u092f \u0915\u094d\u0930\u092e \u092e\u0947\u0902 \u0916\u094b\u0932\u093f\u090f \u0924\u093e\u0915\u093f \u0906\u092a\u0915\u0947 \u092e\u0928 \u092e\u0947\u0902 \u090f\u0915 \u0928\u0915\u094d\u0936\u093e \u092c\u0928\u0947, \u0939\u0930 \u0924\u0938\u094d\u0935\u0940\u0930 \u0915\u094b \u0926\u0947\u0916\u0924\u0947 \u0939\u0940 \u0909\u0938\u0947 \u0928\u093e\u092e \u092f\u093e \u091c\u0917\u0939 \u0915\u093e \u091f\u0948\u0917 \u0926\u0940\u091c\u093f\u090f, \u0914\u0930 \u091c\u092c \u0906\u092a\u0915\u094b \u0932\u0917\u0947 \u0915\u093f \u0915\u093f\u0938\u0940 \u091c\u094b\u0921\u093c\u0940 \u0915\u093e \u092a\u0924\u093e \u0939\u0948, \u0924\u094b \u0905\u0928\u093f\u0936\u094d\u091a\u093f\u0924 \u0915\u093e\u0930\u094d\u0921 \u0915\u094b \u092a\u0939\u0932\u0947 \u092a\u0932\u091f\u093f\u090f \u2014 \u0907\u0938 \u0924\u0930\u0939 \u0917\u093c\u0932\u0924 \u0905\u0902\u0926\u093e\u091c\u093c\u093e \u092d\u0940 \u0906\u092a\u0915\u094b \u0915\u0941\u091b \u0938\u093f\u0916\u093e \u0926\u0947\u0924\u093e \u0939\u0948, \u0928 \u0915\u093f \u0915\u093f\u0938\u0940 \u092a\u0915\u094d\u0915\u0940 \u091c\u094b\u0921\u093c\u0940 \u0915\u094b \u092c\u0930\u094d\u092c\u093e\u0926 \u0915\u0930\u0924\u093e \u0939\u0948\u0964"],["\u0917\u094d\u0930\u093f\u0921 \u0915\u093f\u0924\u0928\u093e \u092c\u0921\u093c\u093e \u0939\u094b\u0928\u093e \u091a\u093e\u0939\u093f\u090f?","\u0910\u0938\u0947 \u0906\u0915\u093e\u0930 \u0938\u0947 \u0936\u0941\u0930\u0942 \u0915\u0940\u091c\u093f\u090f \u091c\u093f\u0938\u0947 \u0906\u092a \u0906\u0930\u093e\u092e \u0938\u0947 \u0938\u093e\u092b\u093c \u0915\u0930 \u0938\u0915\u0947\u0902, \u0914\u0930 \u0924\u092d\u0940 \u092c\u0921\u093c\u093e \u0915\u0940\u091c\u093f\u090f \u091c\u092c \u0935\u0939 \u0906\u0938\u093e\u0928 \u0932\u0917\u0928\u0947 \u0932\u0917\u0947\u0964 \u0906\u092a\u0915\u0940 \u0938\u094d\u092e\u0943\u0924\u093f-\u0938\u0940\u092e\u093e \u0938\u0947 \u0915\u0939\u0940\u0902 \u0906\u0917\u0947 \u0915\u093e \u0917\u094d\u0930\u093f\u0921 \u092c\u0938 \u0905\u0902\u0926\u093e\u091c\u093c\u0947\u092c\u093e\u091c\u093c\u0940 \u092c\u0928 \u091c\u093e\u0924\u093e \u0939\u0948, \u091c\u094b \u092f\u093e\u0926\u0926\u093e\u0936\u094d\u0924 \u0938\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u091d\u0941\u0901\u091d\u0932\u093e\u0939\u091f \u0915\u094b \u0938\u0927\u093e\u0924\u093e \u0939\u0948\u0964"]],variants:"\u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0917\u094d\u0930\u093f\u0921 \u0915\u0947 \u0906\u0915\u093e\u0930 \u0938\u0947 \u092c\u0926\u0932\u0924\u0947 \u0939\u0948\u0902 (\u0906\u0938\u093e\u0928 4x4 \u0938\u0947 \u0932\u0947\u0915\u0930 \u092c\u0921\u093c\u0947 \u092c\u094b\u0930\u094d\u0921 \u0924\u0915), \u0938\u093e\u092e\u0917\u094d\u0930\u0940 \u0938\u0947 (\u091c\u093e\u0928\u0935\u0930, \u091a\u093f\u0939\u094d\u0928, \u0938\u0902\u0916\u094d\u092f\u093e\u090f\u0901, \u0936\u092c\u094d\u0926, \u092f\u093e \u0938\u0940\u0916\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0936\u092c\u094d\u0926-\u0938\u0947-\u0924\u0938\u094d\u0935\u0940\u0930 \u091c\u094b\u0921\u093c\u093f\u092f\u093e\u0901), \u0914\u0930 \u0928\u093f\u092f\u092e\u094b\u0902 \u0938\u0947 \u2014 \u0938\u092e\u092f\u092c\u0926\u094d\u0927 \u092f\u093e \u091a\u093e\u0932-\u0938\u0940\u092e\u093f\u0924 \u0916\u0947\u0932, \u0905\u0915\u0947\u0932\u0947 \u0905\u092a\u0928\u0947 \u0939\u0940 \u0930\u093f\u0915\u0949\u0930\u094d\u0921 \u0915\u0947 \u0916\u093c\u093f\u0932\u093e\u092b\u093c \u092f\u093e \u0926\u0942\u0938\u0930\u094b\u0902 \u0915\u0947 \u0938\u093e\u0925 \u092c\u093e\u0930\u0940-\u092c\u093e\u0930\u0940 \u0938\u0947, \u0914\u0930 \u0915\u0920\u093f\u0928 \u092e\u094b\u0921 \u091c\u0939\u093e\u0901 \u0915\u093e\u0930\u094d\u0921 \u0905\u092a\u0928\u0940 \u091c\u0917\u0939\u0947\u0902 \u092c\u0926\u0932 \u0932\u0947\u0924\u0947 \u0939\u0948\u0902 \u092f\u093e \u091c\u0939\u093e\u0901 \u0906\u092a\u0915\u094b \u091c\u094b\u0921\u093c\u0940 \u0915\u0947 \u092c\u091c\u093e\u092f \u0924\u0940\u0928 \u0915\u093e\u0930\u094d\u0921 \u092e\u093f\u0932\u093e\u0928\u0947 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902\u0964"},zh:{about:"\u300c\u56fe\u7247\u914d\u5bf9\u300d\u628a\u4e00\u7ec4\u5361\u7247\u6b63\u9762\u671d\u4e0b\u94fa\u6210\u65b9\u9635\uff0c\u6bcf\u5f20\u56fe\u6848\u6070\u597d\u51fa\u73b0\u4e24\u6b21\u3002\u6bcf\u56de\u5408\u7ffb\u5f00\u4e24\u5f20\uff1a\u5982\u679c\u914d\u6210\u4e00\u5bf9\uff0c\u8fd9\u5bf9\u5c31\u4fdd\u6301\u7ffb\u5f00\u5e76\u88ab\u6e05\u9664\uff1b\u5982\u679c\u4e0d\u5339\u914d\uff0c\u5c31\u91cd\u65b0\u76d6\u56de\uff0c\u4f60\u518d\u7ee7\u7eed\u5c1d\u8bd5\u3002\u76ee\u6807\u662f\u7528\u5c3d\u91cf\u5c11\u7684\u7ffb\u724c\u6b21\u6570\u6e05\u7a7a\u6574\u4e2a\u68cb\u76d8\u3002",benefit:"\u5b83\u4e3b\u8981\u8bad\u7ec3\u89c6\u89c9\u77ed\u65f6\u8bb0\u5fc6\u548c\u5de5\u4f5c\u8bb0\u5fc6\u2014\u2014\u8bb0\u4f4f\u67d0\u5f20\u5361\u7247\u5728\u54ea\u91cc\uff0c\u518d\u628a\u5b83\u548c\u5f53\u524d\u770b\u5230\u7684\u5361\u7247\u5bf9\u4e0a\u3002\u540c\u65f6\u4e5f\u7528\u5230\u6301\u7eed\u6027\u6ce8\u610f\u529b\u548c\u4e00\u70b9\u7a7a\u95f4\u8bb0\u5fc6\uff0c\u56e0\u4e3a\u4f60\u8981\u4e0d\u65ad\u8ffd\u8e2a\u6bcf\u5f20\u5361\u5728\u65b9\u9635\u91cc\u7684\u4f4d\u7f6e\u3002",history:"\u914d\u5bf9\u7684\u73a9\u6cd5\u975e\u5e38\u53e4\u8001\uff1a\u65e5\u672c\u7684\u8d1d\u5408\uff08kai-awase\uff0c\u8d1d\u58f3\u914d\u5bf9\u6e38\u620f\uff09\u53ef\u8ffd\u6eaf\u5230\u5e73\u5b89\u65f6\u4ee3\uff08\u7ea6\u516c\u51438\u81f312\u4e16\u7eaa\uff09\u3002\u4f5c\u4e3a\u7eb8\u724c\u6e38\u620f\uff0c\u5b83\u572820\u4e16\u7eaa\u4ee5\u5404\u79cd\u540d\u5b57\u6d41\u4f20\u5f00\u6765\u2014\u2014Pelmanism\uff08\u89c1\u4e8e1923\u5e74\u7684\u300aHoyle's Games Modernized\u300b\uff09\u3001Concentration\u3001Pairs\u3001Pexeso\u7b49\uff1b\u800c\u771f\u6b63\u8ba9\u5b83\u4ee5\u5546\u4e1a\u5f62\u5f0f\u8d70\u7ea2\u7684\uff0c\u662fRavensburger\u4e8e1959\u5e74\u63a8\u51fa\u7684\u76d2\u88c5\u6e38\u620f\u300aMemory\u300b\u3002",creator:"\u5b83\u6ca1\u6709\u5355\u4e00\u7684\u53d1\u660e\u8005\uff0c\u800c\u662f\u51fa\u81ea\u5e7f\u4e49\u300c\u914d\u5bf9\u300d\u4f20\u7edf\u7684\u4e00\u6b3e\u516c\u5171\u9886\u57df\u4f20\u7edf\u6e38\u620f\uff0c\u5176\u65e9\u671f\u7956\u5148\u662f\u5e73\u5b89\u65f6\u4ee3\u65e5\u672c\u7684\u8d1d\u5408\uff08kai-awase\uff09\u3002\u5e7f\u4e3a\u4eba\u77e5\u7684\u76d2\u88c5\u7248\u300aMemory\u300b\u7531Ravensburger\u4e8e1959\u5e74\u51fa\u7248\uff0c\u636e\u8bf4\u662f\u4ece\u4e00\u6b3e\u81ea\u5236\u7684\u5bb6\u5ead\u6e38\u620f\u53d1\u5c55\u800c\u6765\uff0c\u800c\u975e\u7531\u67d0\u4e00\u4f4d\u4f5c\u8005\u4ece\u96f6\u8bbe\u8ba1\u3002",methods:"\u522b\u968f\u624b\u4e71\u7ffb\u2014\u2014\u8981\u6709\u6761\u7406\uff0c\u6bd4\u5982\u4e00\u884c\u4e00\u884c\u5730\u6765\uff0c\u8ba9\u6bcf\u5f20\u65b0\u7ffb\u5f00\u7684\u5361\u90fd\u7ed9\u4f60\u6700\u591a\u7684\u4fe1\u606f\u3002\u7ffb\u5f00\u5361\u7247\u65f6\u5c1d\u8bd5\u7528\u8bed\u8a00\u6216\u4f4d\u7f6e\u7ed9\u5b83\u505a\u6807\u8bb0\uff08\u300c\u673a\u5668\u4eba\u5728\u5de6\u4e0a\u89d2\u300d\uff09\uff0c\u5148\u7ffb\u4f60\u6700\u6ca1\u628a\u63e1\u7684\u90a3\u5f20\uff0c\u4ee5\u514d\u767d\u767d\u6d6a\u8d39\u4e00\u4e2a\u5df2\u77e5\u7684\u914d\u5bf9\u3002\u8282\u594f\u4fdd\u6301\u5e73\u7a33\uff0c\u522b\u56fe\u5feb\uff0c\u56e0\u4e3a\u4e00\u6b21\u9a6c\u864e\u7684\u7ffb\u724c\u5c31\u4f1a\u628a\u4f60\u672c\u5df2\u8bb0\u4f4f\u7684\u4e00\u5bf9\u91cd\u65b0\u6253\u4e71\u3002",duration:"\u77ed\u65f6\u6bb5\u7ec3\u4e60\u6548\u679c\u6700\u597d\uff1a\u6bcf\u6b21\u7ea65\u523015\u5206\u949f\uff0c\u4e00\u5468\u51e0\u6b21\u3002\u628a\u4f60\u7684\u7ffb\u724c\u6b21\u6570\u6216\u5b8c\u6210\u65f6\u95f4\u5f53\u6210\u8981\u8d85\u8d8a\u7684\u6210\u7ee9\uff0c\u53ea\u6709\u5f53\u67d0\u4e2a\u96be\u5ea6\u73a9\u8d77\u6765\u8f7b\u677e\u4e86\uff0c\u518d\u52a0\u5927\u65b9\u9635\u5c3a\u5bf8\uff0c\u800c\u4e0d\u662f\u5728\u540c\u4e00\u4e2a\u68cb\u76d8\u4e0a\u6b7b\u78e8\u597d\u51e0\u4e2a\u5c0f\u65f6\u3002",research:"\u8bc1\u636e\u6700\u6709\u529b\u7684\u6070\u6070\u662f\u4f60\u80fd\u60f3\u5230\u7684\u90a3\u90e8\u5206\u2014\u2014\u4f60\u5728\u8fd9\u7c7b\u914d\u5bf9\u4efb\u52a1\u4e0a\u3001\u5728\u8bb0\u4f4f\u5361\u7247\u4f4d\u7f6e\u4e0a\u4f1a\u660e\u663e\u8fdb\u6b65\uff0c\u8fd9\u662f\u5b9e\u5b9e\u5728\u5728\u7684\u8fd1\u8fc1\u79fb\u3002\u81f3\u4e8e\u5b83\u80fd\u63d0\u5347\u6574\u4f53\u8bb0\u5fc6\u3001\u9632\u6b62\u4e0e\u5e74\u9f84\u76f8\u5173\u7684\u8870\u9000\u6216\u63d0\u9ad8\u667a\u529b\u4e4b\u7c7b\u7684\u5bbd\u6cdb\u8bf4\u6cd5\uff0c\u4f9d\u636e\u5219\u5f31\u5f97\u591a\uff1a\u5927\u578b\u7efc\u8ff0\u53d1\u73b0\uff0c\u5de5\u4f5c\u8bb0\u5fc6\u548c\u8111\u8bad\u7ec3\u6e38\u620f\u5f88\u5c11\u80fd\u4ea7\u751f\u5bf9\u672a\u8bad\u7ec3\u80fd\u529b\u7684\u300c\u8fdc\u8fc1\u79fb\u300d\uff0c\u800c\u300c\u6b64\u7c7b\u8bad\u7ec3\u80fd\u63d0\u5347\u6d41\u4f53\u667a\u529b\u300d\u8fd9\u4e00\u62db\u724c\u7ed3\u8bba\u4e5f\u5c61\u6b21\u65e0\u6cd5\u88ab\u91cd\u590d\uff0c\u6240\u4ee5\u5bf9\u90a3\u4e9b\u5b8f\u5927\u627f\u8bfa\u8981\u4fdd\u6301\u8c28\u614e\u3002",rec:"\u7528\u77ed\u65f6\u3001\u4e13\u6ce8\u7684\u5c0f\u6bb5\u6765\u73a9\uff0c\u548c\u81ea\u5df1\u7684\u6700\u4f73\u7ffb\u724c\u7eaa\u5f55\u8f83\u52b2\uff0c\u800c\u4e0d\u662f\u53bb\u8ffd\u9010\u4ec0\u4e48\u300c\u8ba9\u5927\u8111\u53d8\u66f4\u597d\u300d\u7684\u627f\u8bfa\u3002",faq:[["\u73a9\u300c\u56fe\u7247\u914d\u5bf9\u300d\u771f\u7684\u80fd\u6539\u5584\u6211\u7684\u8bb0\u5fc6\u5417\uff1f","\u5b83\u786e\u5b9e\u80fd\u53ef\u9760\u5730\u6539\u5584\u4f60\u5728\u8fd9\u7c7b\u4efb\u52a1\u4e0a\u7684\u8bb0\u5fc6\u2014\u2014\u627e\u5230\u5e76\u56de\u60f3\u5339\u914d\u7684\u5361\u7247\u3002\u81f3\u4e8e\u8fd9\u80fd\u4e0d\u80fd\u8fc1\u79fb\u5230\u65e5\u5e38\u8bb0\u5fc6\uff0c\u8bc1\u636e\u5e76\u4e0d\u5145\u5206\uff1b\u8001\u5b9e\u8bf4\uff0c\u5408\u7406\u7684\u9884\u671f\u662f\u4f60\u53ea\u4f1a\u5728\u8fd9\u4e2a\u6e38\u620f\u672c\u8eab\u4e0a\u53d8\u5f97\u66f4\u597d\u3002"],["\u6709\u4ec0\u4e48\u597d\u7b56\u7565\u80fd\u7528\u66f4\u5c11\u7684\u6b65\u6570\u8d62\uff1f","\u6309\u56fa\u5b9a\u987a\u5e8f\u9010\u5f20\u7ffb\u5f00\uff0c\u4ece\u800c\u5728\u8111\u4e2d\u5efa\u7acb\u4e00\u5f20\u5730\u56fe\uff1b\u6bcf\u770b\u5230\u4e00\u5f20\u56fe\u5c31\u7528\u540d\u5b57\u6216\u4f4d\u7f6e\u7ed9\u5b83\u6253\u6807\u7b7e\uff1b\u5f53\u4f60\u89c9\u5f97\u81ea\u5df1\u77e5\u9053\u4e00\u5bf9\u5728\u54ea\u65f6\uff0c\u5148\u7ffb\u4e0d\u786e\u5b9a\u7684\u90a3\u5f20\u2014\u2014\u8fd9\u6837\u5373\u4f7f\u731c\u9519\uff0c\u4e5f\u80fd\u5b66\u5230\u70b9\u4e1c\u897f\uff0c\u800c\u4e0d\u662f\u767d\u767d\u6d6a\u8d39\u4e00\u4e2a\u7a33\u8d62\u7684\u914d\u5bf9\u3002"],["\u65b9\u9635\u5e94\u8be5\u9009\u591a\u5927\uff1f","\u4ece\u4e00\u4e2a\u4f60\u80fd\u8f7b\u677e\u6e05\u7a7a\u7684\u5c3a\u5bf8\u5f00\u59cb\uff0c\u7b49\u89c9\u5f97\u7b80\u5355\u4e86\u518d\u52a0\u5927\u3002\u8fdc\u8d85\u4f60\u8bb0\u5fc6\u5e7f\u5ea6\u7684\u65b9\u9635\u53ea\u4f1a\u53d8\u6210\u778e\u731c\uff0c\u90a3\u7ec3\u51fa\u6765\u7684\u662f\u632b\u8d25\u611f\u800c\u4e0d\u662f\u8bb0\u5fc6\u3002"]],variants:"\u7248\u672c\u4e4b\u95f4\u7684\u5dee\u5f02\u4f53\u73b0\u5728\u65b9\u9635\u5c3a\u5bf8\uff08\u7b80\u5355\u76844\xd74\u5230\u5927\u68cb\u76d8\uff09\u3001\u5185\u5bb9\uff08\u52a8\u7269\u3001\u7b26\u53f7\u3001\u6570\u5b57\u3001\u5355\u8bcd\uff0c\u6216\u7528\u4e8e\u5b66\u4e60\u7684\u300c\u8bcd\u2014\u56fe\u300d\u914d\u5bf9\uff09\u4ee5\u53ca\u89c4\u5219\u2014\u2014\u9650\u65f6\u6216\u9650\u6b65\u73a9\u6cd5\u3001\u5355\u4eba\u6311\u6218\u81ea\u5df1\u7684\u7eaa\u5f55\u6216\u4e0e\u4ed6\u4eba\u8f6e\u6d41\u51fa\u624b\uff0c\u8fd8\u6709\u66f4\u96be\u7684\u6a21\u5f0f\uff1a\u5361\u7247\u4f1a\u91cd\u65b0\u6d17\u4f4d\uff0c\u6216\u8005\u8981\u914d\u6210\u4e09\u5f20\u4e00\u7ec4\u800c\u975e\u4e00\u5bf9\u3002"}},posner:{ru:{about:"\u0421\u0431\u043e\u043a\u0443 \u044d\u043a\u0440\u0430\u043d\u0430 \u043d\u0430 \u043c\u0433\u043d\u043e\u0432\u0435\u043d\u0438\u0435 \u0432\u0441\u043f\u044b\u0445\u0438\u0432\u0430\u0435\u0442 \u043c\u0435\u0442\u043a\u0430 \u0438\u043b\u0438 \u043f\u043e\u044f\u0432\u043b\u044f\u0435\u0442\u0441\u044f \u0441\u0442\u0440\u0435\u043b\u043a\u0430-\u043f\u043e\u0434\u0441\u043a\u0430\u0437\u043a\u0430, \u0437\u0430\u0442\u0435\u043c \u0433\u0434\u0435-\u0442\u043e \u0432\u043e\u0437\u043d\u0438\u043a\u0430\u0435\u0442 \u0446\u0435\u043b\u044c, \u0438 \u043d\u0443\u0436\u043d\u043e \u043a\u0430\u043a \u043c\u043e\u0436\u043d\u043e \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u043d\u0430 \u043d\u0435\u0451 \u043e\u0442\u0440\u0435\u0430\u0433\u0438\u0440\u043e\u0432\u0430\u0442\u044c. \u0427\u0430\u0449\u0435 \u0432\u0441\u0435\u0433\u043e \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u043a\u0430 \u0443\u043a\u0430\u0437\u044b\u0432\u0430\u0435\u0442 \u0442\u0443\u0434\u0430, \u0433\u0434\u0435 \u0446\u0435\u043b\u044c \u0438 \u043f\u0440\u0430\u0432\u0434\u0430 \u043f\u043e\u044f\u0432\u0438\u0442\u0441\u044f (\u0432\u0435\u0440\u043d\u0430\u044f \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u043a\u0430), \u043d\u043e \u0438\u043d\u043e\u0433\u0434\u0430 \u043e\u0431\u043c\u0430\u043d\u044b\u0432\u0430\u0435\u0442 (\u043b\u043e\u0436\u043d\u0430\u044f) \u2014 \u0438 \u0432\u0435\u0441\u044c \u0441\u043c\u044b\u0441\u043b \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u044f \u0432 \u0440\u0430\u0437\u043d\u0438\u0446\u0435 \u043c\u0435\u0436\u0434\u0443 \u0431\u044b\u0441\u0442\u0440\u043e\u0439 \u0438 \u043c\u0435\u0434\u043b\u0435\u043d\u043d\u043e\u0439 \u0440\u0435\u0430\u043a\u0446\u0438\u0435\u0439.",benefit:"\u0422\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u0441\u043a\u0440\u044b\u0442\u043e\u0435 \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0435 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435: \u0443\u043c\u0435\u043d\u0438\u0435 \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0438\u0442\u044c \u043c\u044b\u0441\u043b\u0435\u043d\u043d\u044b\u0439 \xab\u043f\u0440\u043e\u0436\u0435\u043a\u0442\u043e\u0440\xbb \u0432 \u043d\u0443\u0436\u043d\u0443\u044e \u0442\u043e\u0447\u043a\u0443, \u043d\u0435 \u0434\u0432\u0438\u0433\u0430\u044f \u0433\u043b\u0430\u0437\u0430\u043c\u0438, \u0446\u0435\u043f\u043b\u044f\u0442\u044c\u0441\u044f \u0437\u0430 \u043f\u043e\u043b\u0435\u0437\u043d\u0443\u044e \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u043a\u0443 \u0438 \u0431\u044b\u0441\u0442\u0440\u043e \u043f\u0435\u0440\u0435\u043d\u0430\u043f\u0440\u0430\u0432\u043b\u044f\u0442\u044c\u0441\u044f, \u043a\u043e\u0433\u0434\u0430 \u043e\u043d\u0430 \u043e\u043a\u0430\u0437\u0430\u043b\u0430\u0441\u044c \u043b\u043e\u0436\u043d\u043e\u0439. \u041f\u0440\u043e\u0449\u0435 \u0433\u043e\u0432\u043e\u0440\u044f, \u043e\u0442\u0442\u0430\u0447\u0438\u0432\u0430\u0435\u0442 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u0438 \u0433\u0438\u0431\u043a\u043e\u0441\u0442\u044c, \u0441 \u043a\u043e\u0442\u043e\u0440\u043e\u0439 \u0432\u044b \u0440\u0430\u0441\u043f\u0440\u0435\u0434\u0435\u043b\u044f\u0435\u0442\u0435 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u043f\u043e \u043f\u043e\u043b\u044e \u0437\u0440\u0435\u043d\u0438\u044f.",history:"\u041f\u043e\u044f\u0432\u0438\u043b\u0441\u044f \u0438\u0437 \u043f\u043e\u043f\u044b\u0442\u043e\u043a \u043a\u043e\u0433\u043d\u0438\u0442\u0438\u0432\u043d\u043e\u0439 \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u0438 \u043a\u043e\u043d\u0446\u0430 1970-\u0445 \u0438\u0437\u043c\u0435\u0440\u0438\u0442\u044c \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u043e\u0442\u0434\u0435\u043b\u044c\u043d\u043e \u043e\u0442 \u0434\u0432\u0438\u0436\u0435\u043d\u0438\u0439 \u0433\u043b\u0430\u0437. \u041f\u043e\u0441\u043b\u0435 \u0441\u0442\u0430\u0442\u044c\u0438 \u041c\u0430\u0439\u043a\u043b\u0430 \u041f\u043e\u0437\u043d\u0435\u0440\u0430 1980 \u0433\u043e\u0434\u0430 \u044d\u0442\u0430 \u0441\u0445\u0435\u043c\u0430 \u0441\u0442\u0430\u043b\u0430 \u043e\u0434\u043d\u043e\u0439 \u0438\u0437 \u0441\u0430\u043c\u044b\u0445 \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0438\u043c\u044b\u0445 \u0432 \u043e\u0431\u043b\u0430\u0441\u0442\u0438 \u0438 \u0440\u0430\u0437\u043e\u0448\u043b\u0430\u0441\u044c \u043f\u043e \u043d\u0435\u0439\u0440\u043e\u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u0438\u043c \u043a\u043b\u0438\u043d\u0438\u043a\u0430\u043c (\u043e\u0446\u0435\u043d\u043a\u0430 \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u0433\u043e \u0438\u0433\u043d\u043e\u0440\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u044f, \u0421\u0414\u0412\u0413, \u043f\u043e\u0441\u043b\u0435\u0434\u0441\u0442\u0432\u0438\u0439 \u043b\u043e\u043a\u0430\u043b\u044c\u043d\u044b\u0445 \u043f\u043e\u0440\u0430\u0436\u0435\u043d\u0438\u0439 \u043c\u043e\u0437\u0433\u0430), \u0430 \u043f\u043e\u0437\u0436\u0435 \u2014 \u043f\u043e \u043c\u043d\u043e\u0436\u0435\u0441\u0442\u0432\u0443 \u043b\u0430\u0431\u043e\u0440\u0430\u0442\u043e\u0440\u043d\u044b\u0445 \u0438 \u043e\u043d\u043b\u0430\u0439\u043d-\u0432\u0435\u0440\u0441\u0438\u0439.",creator:"\u0421\u043e\u0437\u0434\u0430\u043d \u0430\u043c\u0435\u0440\u0438\u043a\u0430\u043d\u0441\u043a\u0438\u043c \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u043e\u043c \u041c\u0430\u0439\u043a\u043b\u043e\u043c \u041f\u043e\u0437\u043d\u0435\u0440\u043e\u043c, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u043e\u043f\u0438\u0441\u0430\u043b \u0435\u0433\u043e \u0432 \u0441\u0442\u0430\u0442\u044c\u0435 \xab\u041e\u0440\u0438\u0435\u043d\u0442\u0438\u0440\u043e\u0432\u043a\u0430 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f\xbb (Orienting of Attention) \u0432 1980 \u0433\u043e\u0434\u0443. \u0420\u0435\u0444\u043b\u0435\u043a\u0442\u043e\u0440\u043d\u044b\u0439 \u0432\u0430\u0440\u0438\u0430\u043d\u0442 \u0438 \u044d\u0444\u0444\u0435\u043a\u0442 \xab\u0442\u043e\u0440\u043c\u043e\u0436\u0435\u043d\u0438\u044f \u0432\u043e\u0437\u0432\u0440\u0430\u0442\u0430\xbb \u043e\u043f\u0438\u0441\u0430\u043b\u0438 \u041f\u043e\u0437\u043d\u0435\u0440 \u0438 \u0419\u043e\u0430\u0432 \u041a\u043e\u044d\u043d \u0432 1984 \u0433\u043e\u0434\u0443.",methods:"\u0414\u0435\u0440\u0436\u0438\u0442\u0435 \u0432\u0437\u0433\u043b\u044f\u0434 \u0432 \u0446\u0435\u043d\u0442\u0440\u0435 \u0438 \u043d\u0435 \u043f\u043e\u0437\u0432\u043e\u043b\u044f\u0439\u0442\u0435 \u0433\u043b\u0430\u0437\u0430\u043c \u043c\u0435\u0442\u043d\u0443\u0442\u044c\u0441\u044f \u043a \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u043a\u0435 \u2014 \u043d\u0430\u0432\u044b\u043a \u0432 \u0442\u043e\u043c, \u0447\u0442\u043e\u0431\u044b \u0434\u0432\u0438\u0433\u0430\u043b\u043e\u0441\u044c \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435, \u0430 \u043d\u0435 \u0433\u043b\u0430\u0437\u0430. \u0422\u0440\u0435\u043d\u0438\u0440\u0443\u0439\u0442\u0435 \u043e\u0431\u0430 \u0442\u0438\u043f\u0430 \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u043e\u043a: \u0446\u0435\u043d\u0442\u0440\u0430\u043b\u044c\u043d\u0443\u044e \u0441\u0442\u0440\u0435\u043b\u043a\u0443, \u0437\u0430 \u043a\u043e\u0442\u043e\u0440\u043e\u0439 \u0432\u044b \u0441\u043b\u0435\u0434\u0443\u0435\u0442\u0435 \u043e\u0441\u043e\u0437\u043d\u0430\u043d\u043d\u043e (\u044d\u043d\u0434\u043e\u0433\u0435\u043d\u043d\u0430\u044f), \u0438 \u0431\u043e\u043a\u043e\u0432\u0443\u044e \u0432\u0441\u043f\u044b\u0448\u043a\u0443, \u043a\u043e\u0442\u043e\u0440\u0430\u044f \u0445\u0432\u0430\u0442\u0430\u0435\u0442 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u0441\u0430\u043c\u0430 (\u044d\u043a\u0437\u043e\u0433\u0435\u043d\u043d\u0430\u044f). \u041e\u0441\u043e\u0431\u043e\u0435 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u0443\u0434\u0435\u043b\u044f\u0439\u0442\u0435 \u043b\u043e\u0436\u043d\u044b\u043c \u043f\u0440\u043e\u0431\u0430\u043c \u2014 \u0438\u043c\u0435\u043d\u043d\u043e \u0443\u043c\u0435\u043d\u0438\u0435 \u043e\u0442\u043f\u0443\u0441\u0442\u0438\u0442\u044c \u043d\u0435\u0432\u0435\u0440\u043d\u0443\u044e \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u043a\u0443 \u0438 \u043f\u0435\u0440\u0435\u043d\u0430\u0446\u0435\u043b\u0438\u0442\u044c\u0441\u044f \u0434\u0430\u0451\u0442 \u043e\u0441\u043d\u043e\u0432\u043d\u043e\u0439 \u043f\u0440\u0438\u0440\u043e\u0441\u0442.",duration:"\u041b\u0443\u0447\u0448\u0435 \u0432\u0441\u0435\u0433\u043e \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u0435 \u043f\u043e\u0434\u0445\u043e\u0434\u044b: \u043f\u0440\u0438\u043c\u0435\u0440\u043d\u043e 5\u201310 \u043c\u0438\u043d\u0443\u0442 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0440\u0430\u0437 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e. \u0423\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u0435 \u0431\u044b\u0441\u0442\u0440\u043e\u0435 \u0438 \u043e\u0434\u043d\u043e\u043e\u0431\u0440\u0430\u0437\u043d\u043e\u0435, \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u0441\u0430\u0434\u0438\u0442\u0441\u044f \u0431\u044b\u0441\u0442\u0440\u043e \u2014 \u0437\u0430\u043a\u0430\u043d\u0447\u0438\u0432\u0430\u0439\u0442\u0435, \u043f\u043e\u043a\u0430 \u043e\u043d\u043e \u043d\u0435 \u043f\u0440\u0435\u0432\u0440\u0430\u0442\u0438\u043b\u043e\u0441\u044c \u0432 \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0437\u043c, \u0430 \u043d\u0435 \u0432\u044b\u0436\u0438\u043c\u0430\u0439\u0442\u0435 \u0434\u043b\u0438\u043d\u043d\u044b\u043c\u0438 \u0431\u043b\u043e\u043a\u0430\u043c\u0438.",research:"\u0422\u0432\u0451\u0440\u0434\u043e \u0443\u0441\u0442\u0430\u043d\u043e\u0432\u043b\u0435\u043d \u0441\u0430\u043c \u0431\u0430\u0437\u043e\u0432\u044b\u0439 \u044d\u0444\u0444\u0435\u043a\u0442: \u043d\u0430 \u0432\u0435\u0440\u043d\u043e \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u0430\u043d\u043d\u0443\u044e \u0442\u043e\u0447\u043a\u0443 \u0440\u0435\u0430\u0433\u0438\u0440\u0443\u044e\u0442 \u0431\u044b\u0441\u0442\u0440\u0435\u0435, \u043d\u0430 \u043b\u043e\u0436\u043d\u043e \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u0430\u043d\u043d\u0443\u044e \u2014 \u043c\u0435\u0434\u043b\u0435\u043d\u043d\u0435\u0435, \u0430 \u043f\u0440\u0438 \u0431\u043e\u043b\u044c\u0448\u0438\u0445 \u043f\u0430\u0443\u0437\u0430\u0445 \u043c\u0435\u0436\u0434\u0443 \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u043a\u043e\u0439 \u0438 \u0446\u0435\u043b\u044c\u044e \u043f\u0440\u0435\u0438\u043c\u0443\u0449\u0435\u0441\u0442\u0432\u043e \u043f\u0435\u0440\u0435\u0432\u043e\u0440\u0430\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044f \u0432 \xab\u0442\u043e\u0440\u043c\u043e\u0436\u0435\u043d\u0438\u0435 \u0432\u043e\u0437\u0432\u0440\u0430\u0442\u0430\xbb. \u042d\u0442\u0438 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442\u044b \u043d\u0430\u0434\u0451\u0436\u043d\u043e \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u044f\u0442\u0441\u044f, \u0438 \u0441\u0430\u043c\u0430 \u043c\u0435\u0442\u043e\u0434\u0438\u043a\u0430 \u2014 \u043f\u0440\u043e\u0432\u0435\u0440\u0435\u043d\u043d\u044b\u0439 \u043b\u0430\u0431\u043e\u0440\u0430\u0442\u043e\u0440\u043d\u044b\u0439 \u0438\u0437\u043c\u0435\u0440\u0438\u0442\u0435\u043b\u044c. \u0413\u043e\u0440\u0430\u0437\u0434\u043e \u0441\u043b\u0430\u0431\u0435\u0435 \u0438\u0434\u0435\u044f, \u0447\u0442\u043e \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0430 \u0434\u0435\u043b\u0430\u0435\u0442 \u043b\u0443\u0447\u0448\u0435 \u0432\u0430\u0448\u0435 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u0432 \u0431\u044b\u0442\u0443, \u0447\u0442\u0435\u043d\u0438\u0435 \u0438\u043b\u0438 \u043e\u0431\u0449\u0438\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u2014 \u0448\u0438\u0440\u043e\u043a\u043e\u0433\u043e \xab\u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0430\xbb \u043e\u0442 \u0442\u0430\u043a\u0438\u0445 \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u0439 \u043f\u0440\u0430\u043a\u0442\u0438\u0447\u0435\u0441\u043a\u0438 \u043d\u0435 \u0434\u043e\u043a\u0430\u0437\u0430\u043d\u043e, \u0434\u0430 \u0438 \u0437\u0430\u0434\u0443\u043c\u044b\u0432\u0430\u043b\u0430\u0441\u044c \u043e\u043d\u0430 \u0438\u0437\u043c\u0435\u0440\u044f\u0442\u044c \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435, \u0430 \u043d\u0435 \u043f\u0440\u043e\u043a\u0430\u0447\u0438\u0432\u0430\u0442\u044c \u0435\u0433\u043e. \u0421\u0447\u0438\u0442\u0430\u0439\u0442\u0435, \u0447\u0442\u043e \u0443\u043b\u0443\u0447\u0448\u0430\u0435\u0442\u0441\u044f \u0432 \u043f\u0435\u0440\u0432\u0443\u044e \u043e\u0447\u0435\u0440\u0435\u0434\u044c \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442 \u0432 \u0441\u0430\u043c\u043e\u043c \u044d\u0442\u043e\u043c \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u0438.",rec:"\u041f\u0440\u0438\u043a\u043b\u0435\u0439\u0442\u0435 \u0432\u0437\u0433\u043b\u044f\u0434 \u043a \u0442\u043e\u0447\u043a\u0435 \u0432 \u0446\u0435\u043d\u0442\u0440\u0435 \u0438 \u0434\u0432\u0438\u0433\u0430\u0439\u0442\u0435 \u0442\u043e\u043b\u044c\u043a\u043e \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435\u043c \u2014 \u043f\u043e\u0439\u043c\u0430\u043b\u0438, \u0447\u0442\u043e \u0433\u043b\u0430\u0437\u0430 \u0443\u043f\u043e\u043b\u0437\u043b\u0438 \u043a \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u043a\u0435, \u0441\u0431\u0430\u0432\u044c\u0442\u0435 \u0442\u0435\u043c\u043f \u0438 \u0441\u043e\u0431\u0435\u0440\u0438\u0442\u0435\u0441\u044c \u0437\u0430\u043d\u043e\u0432\u043e.",faq:[["\u041c\u043e\u0436\u043d\u043e \u043b\u0438 \u0441\u043c\u043e\u0442\u0440\u0435\u0442\u044c \u043d\u0430 \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u043a\u0443?","\u041d\u0435\u0442 \u2014 \u0432\u0435\u0441\u044c \u0441\u043c\u044b\u0441\u043b \u0432 \u0442\u043e\u043c, \u0447\u0442\u043e\u0431\u044b \u043f\u0435\u0440\u0435\u043d\u0435\u0441\u0442\u0438 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435, \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u044f \u0432\u0437\u0433\u043b\u044f\u0434 \u0432 \u0446\u0435\u043d\u0442\u0440\u0435. \u0415\u0441\u043b\u0438 \u0434\u0432\u0438\u0433\u0430\u0442\u044c \u0433\u043b\u0430\u0437\u0430\u043c\u0438, \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u0435 \u043f\u0440\u0435\u0432\u0440\u0430\u0449\u0430\u0435\u0442\u0441\u044f \u0432 \u0434\u0440\u0443\u0433\u043e\u0435, \u0431\u043e\u043b\u0435\u0435 \u043b\u0451\u0433\u043a\u043e\u0435."],["\u041f\u043e\u0447\u0435\u043c\u0443 \u0438\u043d\u043e\u0433\u0434\u0430 \u044f \u043c\u0435\u0434\u043b\u0435\u043d\u043d\u0435\u0435 \u0438\u043c\u0435\u043d\u043d\u043e \u0442\u0430\u043c, \u043a\u0443\u0434\u0430 \u0443\u043a\u0430\u0437\u0430\u043b\u0430 \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u043a\u0430?","\u0415\u0441\u043b\u0438 \u043c\u0435\u0436\u0434\u0443 \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u043a\u043e\u0439 \u0438 \u0446\u0435\u043b\u044c\u044e \u043f\u0440\u043e\u0445\u043e\u0434\u0438\u0442 \u0434\u043e\u0441\u0442\u0430\u0442\u043e\u0447\u043d\u043e \u0432\u0440\u0435\u043c\u0435\u043d\u0438, \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u043e\u0442\u0442\u0430\u043b\u043a\u0438\u0432\u0430\u0435\u0442\u0441\u044f \u043e\u0442 \u0443\u0436\u0435 \u043f\u0440\u043e\u0432\u0435\u0440\u0435\u043d\u043d\u043e\u0439 \u0442\u043e\u0447\u043a\u0438. \u042d\u0442\u043e \u0437\u0430\u043c\u0435\u0434\u043b\u0435\u043d\u0438\u0435 \u043d\u0430\u0437\u044b\u0432\u0430\u044e\u0442 \u0442\u043e\u0440\u043c\u043e\u0436\u0435\u043d\u0438\u0435\u043c \u0432\u043e\u0437\u0432\u0440\u0430\u0442\u0430 \u2014 \u043d\u043e\u0440\u043c\u0430\u043b\u044c\u043d\u044b\u0439 \u0438 \u0445\u043e\u0440\u043e\u0448\u043e \u0438\u0437\u0443\u0447\u0435\u043d\u043d\u044b\u0439 \u044d\u0444\u0444\u0435\u043a\u0442."],["\u0421\u0442\u0430\u043d\u0435\u0442 \u043b\u0438 \u043e\u0442 \u044d\u0442\u043e\u0433\u043e \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u043b\u0443\u0447\u0448\u0435 \u0432 \u0436\u0438\u0437\u043d\u0438?","\u0421\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u0432 \u0441\u0430\u043c\u043e\u043c \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u0438 \u0440\u0430\u0441\u0442\u0451\u0442 \u043d\u0430\u0434\u0451\u0436\u043d\u043e, \u0430 \u0432\u043e\u0442 \u0434\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432, \u0447\u0442\u043e \u043f\u043e\u043b\u044c\u0437\u0430 \u043f\u0435\u0440\u0435\u0445\u043e\u0434\u0438\u0442 \u043d\u0430 \u043f\u043e\u0432\u0441\u0435\u0434\u043d\u0435\u0432\u043d\u0443\u044e \u043a\u043e\u043d\u0446\u0435\u043d\u0442\u0440\u0430\u0446\u0438\u044e \u0438\u043b\u0438 \u0443\u0447\u0451\u0431\u0443, \u043c\u0430\u043b\u043e. \u0418\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0439\u0442\u0435 \u0435\u0433\u043e \u043a\u0430\u043a \u0442\u043e\u0447\u0435\u0447\u043d\u0443\u044e \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0443 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f, \u0430 \u043d\u0435 \u043a\u0430\u043a \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043e \u043e\u0442 \u0432\u0441\u0435\u0433\u043e."]],variants:"\u0421\u0440\u0435\u0434\u0438 \u0432\u0430\u0440\u0438\u0430\u0446\u0438\u0439 \u2014 \u044d\u043d\u0434\u043e\u0433\u0435\u043d\u043d\u044b\u0435 \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u043a\u0438 (\u0446\u0435\u043d\u0442\u0440\u0430\u043b\u044c\u043d\u0430\u044f \u0441\u0442\u0440\u0435\u043b\u043a\u0430 \u0438\u043b\u0438 \u0441\u0438\u043c\u0432\u043e\u043b, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u043d\u0443\u0436\u043d\u043e \u0438\u0441\u0442\u043e\u043b\u043a\u043e\u0432\u0430\u0442\u044c) \u043f\u0440\u043e\u0442\u0438\u0432 \u044d\u043a\u0437\u043e\u0433\u0435\u043d\u043d\u044b\u0445 (\u0431\u043e\u043a\u043e\u0432\u0430\u044f \u0432\u0441\u043f\u044b\u0448\u043a\u0430, \u0442\u044f\u043d\u0443\u0449\u0430\u044f \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u0441\u0430\u043c\u0430 \u0441\u043e\u0431\u043e\u0439); \u0438\u0437\u043c\u0435\u043d\u0435\u043d\u0438\u0435 \u043f\u0430\u0443\u0437\u044b \u043c\u0435\u0436\u0434\u0443 \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u043a\u043e\u0439 \u0438 \u0446\u0435\u043b\u044c\u044e, \u0447\u0442\u043e\u0431\u044b \u043f\u043e\u0439\u043c\u0430\u0442\u044c \u0442\u043e \u0443\u0441\u043a\u043e\u0440\u0435\u043d\u0438\u0435, \u0442\u043e \u0442\u043e\u0440\u043c\u043e\u0436\u0435\u043d\u0438\u0435 \u0432\u043e\u0437\u0432\u0440\u0430\u0442\u0430; \u0440\u0430\u0437\u043d\u0430\u044f \u0434\u043e\u043b\u044f \u0432\u0435\u0440\u043d\u044b\u0445 \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u043e\u043a; \u0430 \u0442\u0430\u043a\u0436\u0435 \u0432\u0435\u0440\u0441\u0438\u0438 \u043d\u0430 \u0440\u0430\u0437\u043b\u0438\u0447\u0435\u043d\u0438\u0435, \u0433\u0434\u0435 \u0446\u0435\u043b\u044c \u043d\u0430\u0434\u043e \u043e\u043f\u043e\u0437\u043d\u0430\u0442\u044c, \u0430 \u043d\u0435 \u043f\u0440\u043e\u0441\u0442\u043e \u0437\u0430\u043c\u0435\u0442\u0438\u0442\u044c."},en:{about:"A small marker briefly flashes or points to one side of the screen, then a target appears somewhere and you respond to it as fast as you can. Most of the time the cue points to where the target really shows up (a valid cue), but sometimes it misleads you (an invalid cue) \u2014 the gap between your fast and slow reactions is the whole point of the exercise.",benefit:"It trains covert spatial attention: the ability to shift your mental 'spotlight' to a location without moving your eyes, to lock onto a useful cue, and to disengage and redirect when the cue turns out to be wrong. In short, it sharpens how quickly and flexibly you allocate attention across the visual field.",history:"It grew out of cognitive psychology's effort in the late 1970s to measure attention separately from eye movements. After Michael Posner's 1980 paper it became one of the most reproduced setups in the field, spreading into neuropsychology clinics (to assess hemispatial neglect, ADHD and the effects of focal brain damage) and later into countless lab and online versions.",creator:"Created by the American psychologist Michael I. Posner, who introduced it in his 1980 paper 'Orienting of Attention' (Quarterly Journal of Experimental Psychology). The reflexive variant and the 'inhibition of return' effect were described by Posner and Yoav Cohen in 1984.",methods:"Keep your eyes fixed on the centre and resist the urge to dart them toward the cue \u2014 the skill is moving attention, not the eyes. Practise both cue types: a central arrow you choose to follow (endogenous) and a peripheral flash that grabs you automatically (exogenous). Pay attention to invalid trials, since learning to let go of a wrong cue and re-aim is where most of the gain lies.",duration:"Short sessions work best: roughly 5 to 10 minutes, a few times a week. It is fast and repetitive, so attention fades quickly \u2014 stop before it becomes mechanical rather than grinding through long blocks.",research:"What is solidly established is the basic effect itself: people respond faster to validly cued locations and slower to invalidly cued ones, and at longer cue-target gaps the advantage flips into 'inhibition of return.' These findings replicate robustly and the task is a trusted laboratory measure. What is far weaker is the idea that drilling it makes your everyday attention, reading or general intelligence better \u2014 broad 'transfer' from this kind of practice is largely unproven, and it was designed to measure attention, not to upgrade it. Treat improvement mainly as getting better at this specific task.",rec:"Glue your gaze to the centre dot and move only your attention \u2014 if you catch your eyes drifting to the cue, slow down and reset.",faq:[["Am I allowed to look at the cue?","No \u2014 the whole point is to shift attention while keeping your eyes on the centre. Moving your eyes turns it into a different, easier task."],["Why am I sometimes slower right where the cue pointed?","If enough time passes between the cue and the target, attention is pushed away from the already-checked spot. That slowing is called inhibition of return, and it is a normal, well-documented effect."],["Will this make me more focused in daily life?","It reliably makes you quicker at this task, but evidence that the benefit spreads to everyday concentration or studying is weak. Use it as a precise attention drill, not a cure-all."]],variants:"Common variations include endogenous cues (a central arrow or symbol you interpret) versus exogenous cues (a peripheral flash that pulls attention automatically); changing the delay between cue and target to expose facilitation versus inhibition of return; varying how often the cue is valid; and discrimination versions where you must identify the target rather than merely detect it."},es:{about:"Un peque\xf1o marcador parpadea o apunta brevemente a un lado de la pantalla y, a continuaci\xf3n, aparece un objetivo en alg\xfan lugar al que debes responder lo m\xe1s r\xe1pido posible. La mayor\xeda de las veces la se\xf1al apunta al sitio donde el objetivo realmente surge (una se\xf1al v\xe1lida), pero a veces te enga\xf1a (una se\xf1al inv\xe1lida): la diferencia entre tus reacciones r\xe1pidas y lentas es justo el sentido del ejercicio.",benefit:"Entrena la atenci\xf3n espacial encubierta: la capacidad de desplazar tu 'foco' mental hacia un lugar sin mover los ojos, de fijarte en una se\xf1al \xfatil y de soltarla y reorientarte cuando la se\xf1al resulta equivocada. En resumen, afina la rapidez y la flexibilidad con que repartes la atenci\xf3n por el campo visual.",history:"Surgi\xf3 del esfuerzo de la psicolog\xeda cognitiva, a finales de los a\xf1os setenta, por medir la atenci\xf3n al margen de los movimientos oculares. Tras el art\xedculo de Michael Posner de 1980 se convirti\xf3 en uno de los montajes m\xe1s reproducidos del campo y se extendi\xf3 a las cl\xednicas de neuropsicolog\xeda (para evaluar la negligencia hemiespacial, el TDAH y los efectos del da\xf1o cerebral focal) y, m\xe1s tarde, a innumerables versiones de laboratorio y en l\xednea.",creator:"Creada por el psic\xf3logo estadounidense Michael I. Posner, que la present\xf3 en su art\xedculo de 1980 'Orienting of Attention' (Quarterly Journal of Experimental Psychology). La variante reflexiva y el efecto de 'inhibici\xf3n de retorno' fueron descritos por Posner y Yoav Cohen en 1984.",methods:"Mant\xe9n la mirada fija en el centro y resiste el impulso de lanzarla hacia la se\xf1al: la habilidad consiste en mover la atenci\xf3n, no los ojos. Practica ambos tipos de se\xf1al: una flecha central que decides seguir (end\xf3gena) y un destello perif\xe9rico que te capta de forma autom\xe1tica (ex\xf3gena). Presta atenci\xf3n a los ensayos inv\xe1lidos, ya que aprender a soltar una se\xf1al equivocada y reorientarte es donde est\xe1 la mayor parte de la ganancia.",duration:"Lo mejor son las sesiones cortas: unos 5 a 10 minutos, algunas veces por semana. Es r\xe1pido y repetitivo, as\xed que la atenci\xf3n se desvanece pronto; para antes de que se vuelva mec\xe1nico en lugar de aguantar bloques largos.",research:"Lo que est\xe1 s\xf3lidamente establecido es el efecto b\xe1sico en s\xed: la gente responde m\xe1s r\xe1pido a los lugares se\xf1alados de forma v\xe1lida y m\xe1s lento a los se\xf1alados de forma inv\xe1lida, y con intervalos m\xe1s largos entre se\xf1al y objetivo la ventaja se invierte y aparece la 'inhibici\xf3n de retorno'. Estos hallazgos se replican de forma robusta y la tarea es una medida de laboratorio fiable. Mucho m\xe1s d\xe9bil es la idea de que machacarla mejore tu atenci\xf3n cotidiana, la lectura o la inteligencia general: la 'transferencia' amplia de este tipo de pr\xe1ctica est\xe1 en gran medida sin demostrar, y fue dise\xf1ada para medir la atenci\xf3n, no para mejorarla. Toma la mejora sobre todo como volverte mejor en esta tarea concreta.",rec:"Pega la mirada al punto central y mueve solo la atenci\xf3n; si notas que los ojos se te van hacia la se\xf1al, baja el ritmo y reinicia.",faq:[["\xbfPuedo mirar la se\xf1al?","No: todo el sentido es desplazar la atenci\xf3n mientras mantienes los ojos en el centro. Mover los ojos lo convierte en una tarea distinta y m\xe1s f\xe1cil."],["\xbfPor qu\xe9 a veces voy m\xe1s lento justo donde apuntaba la se\xf1al?","Si pasa suficiente tiempo entre la se\xf1al y el objetivo, la atenci\xf3n se aleja del punto ya comprobado. Esa lentitud se llama inhibici\xf3n de retorno y es un efecto normal y bien documentado."],["\xbfEsto me har\xe1 estar m\xe1s concentrado en el d\xeda a d\xeda?","Te hace de forma fiable m\xe1s r\xe1pido en esta tarea, pero la evidencia de que el beneficio se extienda a la concentraci\xf3n cotidiana o al estudio es d\xe9bil. \xdasalo como un ejercicio preciso de atenci\xf3n, no como un remedio universal."]],variants:"Entre las variaciones habituales est\xe1n las se\xf1ales end\xf3genas (una flecha o s\xedmbolo central que interpretas) frente a las ex\xf3genas (un destello perif\xe9rico que tira de la atenci\xf3n de forma autom\xe1tica); cambiar el retardo entre se\xf1al y objetivo para sacar a la luz la facilitaci\xf3n frente a la inhibici\xf3n de retorno; variar la frecuencia con que la se\xf1al es v\xe1lida; y versiones de discriminaci\xf3n en las que debes identificar el objetivo en lugar de solo detectarlo."},de:{about:"Eine kleine Markierung blitzt kurz auf oder zeigt auf eine Seite des Bildschirms, dann erscheint irgendwo ein Ziel, auf das du so schnell wie m\xf6glich reagierst. Meistens deutet der Hinweisreiz dorthin, wo das Ziel wirklich auftaucht (ein g\xfcltiger Hinweis), manchmal f\xfchrt er dich aber in die Irre (ein ung\xfcltiger Hinweis) \u2013 der Unterschied zwischen deinen schnellen und langsamen Reaktionen ist der ganze Sinn der \xdcbung.",benefit:"Trainiert wird die verdeckte r\xe4umliche Aufmerksamkeit: die F\xe4higkeit, dein gedankliches \u201eScheinwerferlicht\u201c auf einen Ort zu verschieben, ohne die Augen zu bewegen, einen n\xfctzlichen Hinweis zu fixieren und dich zu l\xf6sen und umzulenken, wenn sich der Hinweis als falsch erweist. Kurz: Sie sch\xe4rft, wie schnell und flexibel du Aufmerksamkeit \xfcber das Sichtfeld verteilst.",history:"Sie entstand aus dem Bem\xfchen der kognitiven Psychologie in den sp\xe4ten 1970er-Jahren, Aufmerksamkeit getrennt von Augenbewegungen zu messen. Nach Michael Posners Arbeit von 1980 wurde sie zu einem der meistreproduzierten Versuchsaufbauten des Feldes und verbreitete sich in neuropsychologische Kliniken (zur Erfassung von Hemineglect, ADHS und den Folgen umschriebener Hirnsch\xe4den) und sp\xe4ter in unz\xe4hlige Labor- und Online-Versionen.",creator:"Entwickelt vom amerikanischen Psychologen Michael I. Posner, der sie in seiner Arbeit von 1980 \u201eOrienting of Attention\u201c (Quarterly Journal of Experimental Psychology) vorstellte. Die reflexive Variante und der Effekt der \u201eInhibition of Return\u201c wurden 1984 von Posner und Yoav Cohen beschrieben.",methods:"Halte den Blick fest auf der Mitte und widersteh dem Drang, ihn zum Hinweis hin\xfcberzucken zu lassen \u2013 die Fertigkeit besteht darin, die Aufmerksamkeit zu bewegen, nicht die Augen. \xdcbe beide Hinweisarten: einen zentralen Pfeil, dem du bewusst folgst (endogen), und ein peripheres Aufblitzen, das dich automatisch packt (exogen). Achte auf die ung\xfcltigen Durchg\xe4nge, denn zu lernen, einen falschen Hinweis loszulassen und neu auszurichten, ist der Punkt, an dem der meiste Gewinn liegt.",duration:"Kurze Sitzungen funktionieren am besten: etwa 5 bis 10 Minuten, ein paar Mal pro Woche. Die Aufgabe ist schnell und repetitiv, daher l\xe4sst die Aufmerksamkeit rasch nach \u2013 h\xf6r auf, bevor es mechanisch wird, statt dich durch lange Bl\xf6cke zu qu\xe4len.",research:"Solide belegt ist der Grundeffekt selbst: Menschen reagieren schneller auf g\xfcltig angek\xfcndigte Orte und langsamer auf ung\xfcltig angek\xfcndigte, und bei l\xe4ngeren Hinweis-Ziel-Abst\xe4nden kippt der Vorteil in eine \u201eInhibition of Return\u201c. Diese Befunde replizieren robust, und die Aufgabe gilt als verl\xe4ssliches Laborma\xdf. Deutlich schw\xe4cher ist die Vorstellung, dass das \xdcben deine allt\xe4gliche Aufmerksamkeit, dein Lesen oder deine allgemeine Intelligenz verbessert \u2013 ein breiter \u201eTransfer\u201c aus dieser Art von Training ist weitgehend unbewiesen, und die Aufgabe wurde geschaffen, um Aufmerksamkeit zu messen, nicht um sie aufzur\xfcsten. Werte Verbesserung vor allem als Besserwerden in genau dieser Aufgabe.",rec:"Klebe deinen Blick an den Mittelpunkt und bewege nur deine Aufmerksamkeit \u2013 wenn du merkst, dass deine Augen zum Hinweis abdriften, werde langsamer und setz neu an.",faq:[["Darf ich den Hinweis ansehen?","Nein \u2013 der ganze Sinn ist, die Aufmerksamkeit zu verschieben, w\xe4hrend die Augen auf der Mitte bleiben. Die Augen zu bewegen macht daraus eine andere, leichtere Aufgabe."],["Warum bin ich manchmal genau dort langsamer, wohin der Hinweis gezeigt hat?","Wenn zwischen Hinweis und Ziel genug Zeit vergeht, wird die Aufmerksamkeit von dem schon gepr\xfcften Ort weggedr\xe4ngt. Diese Verlangsamung hei\xdft Inhibition of Return und ist ein normaler, gut dokumentierter Effekt."],["Macht mich das im Alltag konzentrierter?","Es macht dich zuverl\xe4ssig schneller in dieser Aufgabe, aber die Belege, dass sich der Nutzen auf allt\xe4gliche Konzentration oder das Lernen \xfcbertr\xe4gt, sind schwach. Nutze es als pr\xe4zise Aufmerksamkeits\xfcbung, nicht als Allheilmittel."]],variants:"H\xe4ufige Variationen sind endogene Hinweise (ein zentraler Pfeil oder ein Symbol, das du deutest) gegen\xfcber exogenen Hinweisen (ein peripheres Aufblitzen, das die Aufmerksamkeit automatisch anzieht); das Ver\xe4ndern des Abstands zwischen Hinweis und Ziel, um Erleichterung gegen\xfcber Inhibition of Return sichtbar zu machen; das Variieren, wie oft der Hinweis g\xfcltig ist; und Unterscheidungsversionen, bei denen du das Ziel identifizieren musst, statt es nur zu entdecken."},pt:{about:"Um pequeno marcador pisca brevemente ou aponta para um dos lados do ecr\xe3 e, em seguida, um alvo surge em algum ponto e voc\xea responde a ele o mais r\xe1pido que conseguir. Na maioria das vezes a pista aponta para onde o alvo realmente aparece (pista v\xe1lida), mas \xe0s vezes ela engana voc\xea (pista inv\xe1lida) \u2014 a diferen\xe7a entre as suas rea\xe7\xf5es r\xe1pidas e lentas \xe9 todo o objetivo do exerc\xedcio.",benefit:"Treina a aten\xe7\xe3o espacial encoberta: a capacidade de deslocar o seu 'holofote' mental para um local sem mover os olhos, de fixar-se numa pista \xfatil e de desengatar e redirecionar quando a pista se revela errada. Em resumo, aperfei\xe7oa a rapidez e a flexibilidade com que voc\xea distribui a aten\xe7\xe3o pelo campo visual.",history:"Surgiu do esfor\xe7o da psicologia cognitiva, no final dos anos 1970, de medir a aten\xe7\xe3o separadamente dos movimentos oculares. Ap\xf3s o artigo de Michael Posner em 1980, tornou-se um dos arranjos mais reproduzidos da \xe1rea, espalhando-se pelas cl\xednicas de neuropsicologia (para avaliar neglig\xeancia hemiespacial, TDAH e os efeitos de les\xf5es cerebrais focais) e mais tarde por incont\xe1veis vers\xf5es de laborat\xf3rio e online.",creator:"Criado pelo psic\xf3logo norte-americano Michael I. Posner, que o apresentou no seu artigo de 1980 'Orienting of Attention' (Quarterly Journal of Experimental Psychology). A variante reflexa e o efeito de 'inibi\xe7\xe3o de retorno' foram descritos por Posner e Yoav Cohen em 1984.",methods:"Mantenha os olhos fixos no centro e resista \xe0 vontade de dispar\xe1-los em dire\xe7\xe3o \xe0 pista \u2014 a habilidade \xe9 mover a aten\xe7\xe3o, n\xe3o os olhos. Pratique os dois tipos de pista: uma seta central que voc\xea escolhe seguir (end\xf3gena) e um flash perif\xe9rico que captura voc\xea automaticamente (ex\xf3gena). Preste aten\xe7\xe3o \xe0s tentativas inv\xe1lidas, pois \xe9 em aprender a largar uma pista errada e a reapontar que est\xe1 a maior parte do ganho.",duration:"As sess\xf5es curtas funcionam melhor: cerca de 5 a 10 minutos, algumas vezes por semana. \xc9 r\xe1pido e repetitivo, por isso a aten\xe7\xe3o esvai-se depressa \u2014 pare antes de virar algo mec\xe2nico, em vez de insistir em blocos longos.",research:"O que est\xe1 solidamente estabelecido \xe9 o efeito b\xe1sico em si: as pessoas respondem mais r\xe1pido a locais validamente indicados e mais devagar aos indicados de forma inv\xe1lida e, com intervalos pista-alvo mais longos, a vantagem inverte-se na 'inibi\xe7\xe3o de retorno'. Esses achados replicam-se de forma robusta e a tarefa \xe9 uma medida laboratorial de confian\xe7a. Bem mais fraca \xe9 a ideia de que trein\xe1-la torna melhor a sua aten\xe7\xe3o no dia a dia, a leitura ou a intelig\xeancia geral \u2014 a 'transfer\xeancia' ampla a partir deste tipo de pr\xe1tica \xe9 em grande parte n\xe3o comprovada, e ela foi concebida para medir a aten\xe7\xe3o, n\xe3o para melhor\xe1-la. Encare a melhoria sobretudo como ficar melhor nesta tarefa espec\xedfica.",rec:"Cole o olhar no ponto central e mova apenas a aten\xe7\xe3o \u2014 se notar os olhos a deslizar para a pista, desacelere e recomece.",faq:[["Posso olhar para a pista?","N\xe3o \u2014 todo o objetivo \xe9 deslocar a aten\xe7\xe3o mantendo os olhos no centro. Mover os olhos transforma isto numa tarefa diferente e mais f\xe1cil."],["Por que \xe0s vezes sou mais lento justamente onde a pista apontou?","Se passar tempo suficiente entre a pista e o alvo, a aten\xe7\xe3o \xe9 empurrada para longe do ponto j\xe1 verificado. Essa lentid\xe3o chama-se inibi\xe7\xe3o de retorno e \xe9 um efeito normal e bem documentado."],["Isto vai me deixar mais concentrado na vida di\xe1ria?","Torna voc\xea de forma fi\xe1vel mais r\xe1pido nesta tarefa, mas a evid\xeancia de que o benef\xedcio se estende \xe0 concentra\xe7\xe3o ou ao estudo no dia a dia \xe9 fraca. Use-o como um exerc\xedcio de aten\xe7\xe3o preciso, n\xe3o como uma solu\xe7\xe3o para tudo."]],variants:"As varia\xe7\xf5es comuns incluem pistas end\xf3genas (uma seta ou s\xedmbolo central que voc\xea interpreta) versus pistas ex\xf3genas (um flash perif\xe9rico que puxa a aten\xe7\xe3o automaticamente); alterar o atraso entre pista e alvo para expor a facilita\xe7\xe3o versus a inibi\xe7\xe3o de retorno; variar a frequ\xeancia com que a pista \xe9 v\xe1lida; e vers\xf5es de discrimina\xe7\xe3o em que voc\xea precisa identificar o alvo, e n\xe3o apenas detect\xe1-lo."},hi:{about:"\u090f\u0915 \u091b\u094b\u091f\u093e-\u0938\u093e \u0928\u093f\u0936\u093e\u0928 \u0938\u094d\u0915\u094d\u0930\u0940\u0928 \u0915\u0947 \u0915\u093f\u0938\u0940 \u090f\u0915 \u0924\u0930\u092b\u093c \u092a\u0932 \u092d\u0930 \u0915\u0947 \u0932\u093f\u090f \u091a\u092e\u0915\u0924\u093e \u0939\u0948 \u092f\u093e \u0907\u0936\u093e\u0930\u093e \u0915\u0930\u0924\u093e \u0939\u0948, \u092b\u093f\u0930 \u0915\u0939\u0940\u0902 \u090f\u0915 \u0932\u0915\u094d\u0937\u094d\u092f \u092a\u094d\u0930\u0915\u091f \u0939\u094b\u0924\u093e \u0939\u0948 \u0914\u0930 \u0906\u092a\u0915\u094b \u0909\u0938 \u092a\u0930 \u091c\u093f\u0924\u0928\u0940 \u091c\u0932\u094d\u0926\u0940 \u0939\u094b \u0938\u0915\u0947 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0926\u0947\u0928\u0940 \u0939\u094b\u0924\u0940 \u0939\u0948\u0964 \u091c\u093c\u094d\u092f\u093e\u0926\u093e\u0924\u0930 \u092c\u093e\u0930 \u0938\u0902\u0915\u0947\u0924 \u0935\u0939\u0940\u0902 \u0907\u0936\u093e\u0930\u093e \u0915\u0930\u0924\u093e \u0939\u0948 \u091c\u0939\u093e\u0901 \u0932\u0915\u094d\u0937\u094d\u092f \u0938\u091a\u092e\u0941\u091a \u0926\u093f\u0916\u0924\u093e \u0939\u0948 (\u0938\u0939\u0940 \u0938\u0902\u0915\u0947\u0924), \u092a\u0930 \u0915\u092d\u0940-\u0915\u092d\u0940 \u0935\u0939 \u0906\u092a\u0915\u094b \u092d\u091f\u0915\u093e \u0926\u0947\u0924\u093e \u0939\u0948 (\u0917\u0932\u0924 \u0938\u0902\u0915\u0947\u0924) \u2014 \u0906\u092a\u0915\u0940 \u0924\u0947\u091c\u093c \u0914\u0930 \u0927\u0940\u092e\u0940 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e\u0913\u0902 \u0915\u0947 \u092c\u0940\u091a \u0915\u093e \u092f\u0939\u0940 \u092b\u093c\u0930\u094d\u0915 \u0907\u0938 \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u093e \u092a\u0942\u0930\u093e \u092e\u0915\u093c\u0938\u0926 \u0939\u0948\u0964",benefit:"\u092f\u0939 \u091b\u0941\u092a\u0947 \u0939\u0941\u090f \u0938\u094d\u0925\u093e\u0928\u093f\u0915 \u0927\u094d\u092f\u093e\u0928 \u0915\u094b \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u093f\u0924 \u0915\u0930\u0924\u093e \u0939\u0948: \u092f\u093e\u0928\u0940 \u0905\u092a\u0928\u0940 \u092e\u093e\u0928\u0938\u093f\u0915 '\u091f\u0949\u0930\u094d\u091a' \u0915\u094b \u0906\u0901\u0916\u0947\u0902 \u0939\u093f\u0932\u093e\u090f \u092c\u093f\u0928\u093e \u0915\u093f\u0938\u0940 \u091c\u0917\u0939 \u0915\u0940 \u0913\u0930 \u0916\u093f\u0938\u0915\u093e\u0928\u0947, \u0915\u093f\u0938\u0940 \u0915\u093e\u092e \u0915\u0947 \u0938\u0902\u0915\u0947\u0924 \u092a\u0930 \u091f\u093f\u0915 \u091c\u093e\u0928\u0947, \u0914\u0930 \u091c\u092c \u0938\u0902\u0915\u0947\u0924 \u0917\u0932\u0924 \u0928\u093f\u0915\u0932\u0947 \u0924\u094b \u0909\u0938\u0938\u0947 \u0939\u091f\u0915\u0930 \u0926\u093f\u0936\u093e \u092c\u0926\u0932 \u0932\u0947\u0928\u0947 \u0915\u0940 \u0915\u094d\u0937\u092e\u0924\u093e\u0964 \u0938\u0902\u0915\u094d\u0937\u0947\u092a \u092e\u0947\u0902, \u092f\u0939 \u0907\u0938 \u092c\u093e\u0924 \u0915\u094b \u092a\u0948\u0928\u093e \u0915\u0930\u0924\u093e \u0939\u0948 \u0915\u093f \u0906\u092a \u0926\u0943\u0936\u094d\u092f-\u0915\u094d\u0937\u0947\u0924\u094d\u0930 \u092e\u0947\u0902 \u0927\u094d\u092f\u093e\u0928 \u0915\u094b \u0915\u093f\u0924\u0928\u0940 \u091c\u0932\u094d\u0926\u0940 \u0914\u0930 \u0915\u093f\u0924\u0928\u0947 \u0932\u091a\u0940\u0932\u0947\u092a\u0928 \u0938\u0947 \u092c\u093e\u0901\u091f\u0924\u0947 \u0939\u0948\u0902\u0964",history:"\u092f\u0939 1970 \u0915\u0947 \u0926\u0936\u0915 \u0915\u0947 \u0906\u0916\u093c\u093f\u0930 \u092e\u0947\u0902 \u0938\u0902\u091c\u094d\u091e\u093e\u0928\u093e\u0924\u094d\u092e\u0915 \u092e\u0928\u094b\u0935\u093f\u091c\u094d\u091e\u093e\u0928 \u0915\u0940 \u0909\u0938 \u0915\u094b\u0936\u093f\u0936 \u0938\u0947 \u0928\u093f\u0915\u0932\u093e \u091c\u093f\u0938\u092e\u0947\u0902 \u0927\u094d\u092f\u093e\u0928 \u0915\u094b \u0906\u0901\u0916\u094b\u0902 \u0915\u0940 \u0917\u0924\u093f \u0938\u0947 \u0905\u0932\u0917 \u0915\u0930\u0915\u0947 \u0928\u093e\u092a\u0928\u0947 \u0915\u0940 \u091a\u093e\u0939 \u0925\u0940\u0964 Michael Posner \u0915\u0947 1980 \u0915\u0947 \u0936\u094b\u0927-\u092a\u0924\u094d\u0930 \u0915\u0947 \u092c\u093e\u0926 \u092f\u0939 \u0907\u0938 \u0915\u094d\u0937\u0947\u0924\u094d\u0930 \u0915\u0947 \u0938\u092c\u0938\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0926\u094b\u0939\u0930\u093e\u090f \u0917\u090f \u0938\u0947\u091f\u0905\u092a\u094b\u0902 \u092e\u0947\u0902 \u0938\u0947 \u090f\u0915 \u092c\u0928 \u0917\u092f\u093e, \u0914\u0930 \u0928\u094d\u092f\u0942\u0930\u094b\u0938\u093e\u0907\u0915\u094b\u0932\u0949\u091c\u0940 \u0915\u094d\u0932\u093f\u0928\u093f\u0915\u094b\u0902 \u0924\u0915 \u092b\u0948\u0932 \u0917\u092f\u093e (\u0939\u0947\u092e\u093f\u0938\u094d\u092a\u0947\u0936\u093f\u092f\u0932 \u0928\u0947\u0917\u094d\u0932\u0947\u0915\u094d\u091f, ADHD \u0914\u0930 \u0938\u094d\u0925\u093e\u0928\u093f\u0915 \u092e\u0938\u094d\u0924\u093f\u0937\u094d\u0915-\u0915\u094d\u0937\u0924\u093f \u0915\u0947 \u0905\u0938\u0930 \u0915\u094b \u092a\u0930\u0916\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f) \u0914\u0930 \u092c\u093e\u0926 \u092e\u0947\u0902 \u0905\u0928\u0917\u093f\u0928\u0924 \u092a\u094d\u0930\u092f\u094b\u0917\u0936\u093e\u0932\u093e \u0914\u0930 \u0911\u0928\u0932\u093e\u0907\u0928 \u0938\u0902\u0938\u094d\u0915\u0930\u0923\u094b\u0902 \u092e\u0947\u0902\u0964",creator:"\u0907\u0938\u0947 \u0905\u092e\u0947\u0930\u093f\u0915\u0940 \u092e\u0928\u094b\u0935\u0948\u091c\u094d\u091e\u093e\u0928\u093f\u0915 Michael I. Posner \u0928\u0947 \u092c\u0928\u093e\u092f\u093e, \u091c\u093f\u0928\u094d\u0939\u094b\u0902\u0928\u0947 \u0907\u0938\u0947 \u0905\u092a\u0928\u0947 1980 \u0915\u0947 \u0936\u094b\u0927-\u092a\u0924\u094d\u0930 'Orienting of Attention' (Quarterly Journal of Experimental Psychology) \u092e\u0947\u0902 \u092a\u0947\u0936 \u0915\u093f\u092f\u093e\u0964 \u092a\u094d\u0930\u0924\u093f\u0935\u0930\u094d\u0924\u0940 (reflexive) \u0930\u0942\u092a \u0914\u0930 'inhibition of return' \u092a\u094d\u0930\u092d\u093e\u0935 \u0915\u093e \u0935\u0930\u094d\u0923\u0928 Posner \u0914\u0930 Yoav Cohen \u0928\u0947 1984 \u092e\u0947\u0902 \u0915\u093f\u092f\u093e\u0964",methods:"\u0905\u092a\u0928\u0940 \u0928\u093f\u0917\u093e\u0939 \u0915\u094b \u092c\u0940\u091a\u094b\u0902-\u092c\u0940\u091a \u091c\u092e\u093e\u090f \u0930\u0916\u0947\u0902 \u0914\u0930 \u0938\u0902\u0915\u0947\u0924 \u0915\u0940 \u0924\u0930\u092b\u093c \u0906\u0901\u0916\u0947\u0902 \u091d\u092a\u091f\u093e\u0928\u0947 \u0915\u0947 \u0932\u093e\u0932\u091a \u0938\u0947 \u092c\u091a\u0947\u0902 \u2014 \u0939\u0941\u0928\u0930 \u0927\u094d\u092f\u093e\u0928 \u0915\u094b \u0939\u093f\u0932\u093e\u0928\u0947 \u0915\u093e \u0939\u0948, \u0906\u0901\u0916\u094b\u0902 \u0915\u094b \u0928\u0939\u0940\u0902\u0964 \u0926\u094b\u0928\u094b\u0902 \u0924\u0930\u0939 \u0915\u0947 \u0938\u0902\u0915\u0947\u0924\u094b\u0902 \u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0930\u0947\u0902: \u090f\u0915 \u092c\u0940\u091a \u092e\u0947\u0902 \u092c\u0928\u093e \u0924\u0940\u0930 \u091c\u093f\u0938\u0947 \u0906\u092a \u091c\u093e\u0928-\u092c\u0942\u091d\u0915\u0930 \u0905\u092a\u0928\u093e\u0924\u0947 \u0939\u0948\u0902 (\u090f\u0928\u094d\u0921\u094b\u091c\u0947\u0928\u0938) \u0914\u0930 \u0915\u093f\u0928\u093e\u0930\u0947 \u0915\u0940 \u090f\u0915 \u091a\u092e\u0915 \u091c\u094b \u0906\u092a\u0915\u094b \u0905\u092a\u0928\u0947-\u0906\u092a \u0916\u0940\u0902\u091a \u0932\u0947\u0924\u0940 \u0939\u0948 (\u090f\u0915\u094d\u0938\u094b\u091c\u0947\u0928\u0938)\u0964 \u0917\u0932\u0924 \u0938\u0902\u0915\u0947\u0924 \u0935\u093e\u0932\u0947 \u091f\u094d\u0930\u093e\u092f\u0932 \u092a\u0930 \u0927\u094d\u092f\u093e\u0928 \u0926\u0947\u0902, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u090f\u0915 \u0917\u0932\u0924 \u0938\u0902\u0915\u0947\u0924 \u0915\u094b \u091b\u094b\u0921\u093c\u0915\u0930 \u0926\u094b\u092c\u093e\u0930\u093e \u0928\u093f\u0936\u093e\u0928\u093e \u0938\u093e\u0927\u0928\u093e \u0938\u0940\u0916\u0928\u093e \u0939\u0940 \u0935\u0939 \u091c\u0917\u0939 \u0939\u0948 \u091c\u0939\u093e\u0901 \u0905\u0927\u093f\u0915\u093e\u0902\u0936 \u092b\u093c\u093e\u092f\u0926\u093e \u091b\u0941\u092a\u093e \u0939\u0948\u0964",duration:"\u091b\u094b\u091f\u0947 \u0938\u0924\u094d\u0930 \u0938\u092c\u0938\u0947 \u0905\u091a\u094d\u091b\u0947 \u0930\u0939\u0924\u0947 \u0939\u0948\u0902: \u0915\u0930\u0940\u092c 5 \u0938\u0947 10 \u092e\u093f\u0928\u091f, \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u0915\u0941\u091b\u0947\u0915 \u092c\u093e\u0930\u0964 \u092f\u0939 \u0924\u0947\u091c\u093c \u0914\u0930 \u0926\u094b\u0939\u0930\u093e\u0935 \u0935\u093e\u0932\u093e \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0927\u094d\u092f\u093e\u0928 \u091c\u0932\u094d\u0926\u0940 \u092e\u0926\u094d\u0927\u092e \u092a\u0921\u093c \u091c\u093e\u0924\u093e \u0939\u0948 \u2014 \u0932\u0902\u092c\u0947-\u0932\u0902\u092c\u0947 \u092c\u094d\u0932\u0949\u0915 \u0930\u091f\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u0907\u0938\u0915\u0947 \u092f\u093e\u0902\u0924\u094d\u0930\u093f\u0915 \u0939\u094b \u091c\u093e\u0928\u0947 \u0938\u0947 \u092a\u0939\u0932\u0947 \u0939\u0940 \u0930\u0941\u0915 \u091c\u093e\u090f\u0901\u0964",research:"\u091c\u094b \u092c\u093e\u0924 \u092a\u0941\u0916\u093c\u094d\u0924\u093e \u0924\u0930\u0940\u0915\u0947 \u0938\u0947 \u0938\u094d\u0925\u093e\u092a\u093f\u0924 \u0939\u0948 \u0935\u0939 \u0939\u0948 \u0916\u0941\u0926 \u092f\u0939 \u092c\u0941\u0928\u093f\u092f\u093e\u0926\u0940 \u092a\u094d\u0930\u092d\u093e\u0935: \u0932\u094b\u0917 \u0938\u0939\u0940 \u0938\u0902\u0915\u0947\u0924 \u0935\u093e\u0932\u0940 \u091c\u0917\u0939\u094b\u0902 \u092a\u0930 \u0924\u0947\u091c\u093c \u0914\u0930 \u0917\u0932\u0924 \u0938\u0902\u0915\u0947\u0924 \u0935\u093e\u0932\u0940 \u091c\u0917\u0939\u094b\u0902 \u092a\u0930 \u0927\u0940\u092e\u0940 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0926\u0947\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u0938\u0902\u0915\u0947\u0924-\u0932\u0915\u094d\u0937\u094d\u092f \u0915\u0947 \u092c\u0940\u091a \u0932\u0902\u092c\u093e \u0905\u0902\u0924\u0930\u093e\u0932 \u0939\u094b\u0928\u0947 \u092a\u0930 \u092f\u0939 \u092c\u0922\u093c\u0924 \u092a\u0932\u091f\u0915\u0930 'inhibition of return' \u092c\u0928 \u091c\u093e\u0924\u0940 \u0939\u0948\u0964 \u092f\u0947 \u0928\u0924\u0940\u091c\u0947 \u092e\u091c\u093c\u092c\u0942\u0924\u0940 \u0938\u0947 \u0926\u094b\u0939\u0930\u093e\u090f \u091c\u093e\u0924\u0947 \u0939\u0948\u0902 \u0914\u0930 \u092f\u0939 \u0915\u093e\u0930\u094d\u092f \u090f\u0915 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u092a\u094d\u0930\u092f\u094b\u0917\u0936\u093e\u0932\u093e \u092e\u093e\u092a \u0939\u0948\u0964 \u091c\u094b \u092c\u093e\u0924 \u0915\u0939\u0940\u0902 \u0915\u092e\u091c\u093c\u094b\u0930 \u0939\u0948 \u0935\u0939 \u092f\u0939 \u0927\u093e\u0930\u0923\u093e \u0939\u0948 \u0915\u093f \u0907\u0938\u0915\u093e \u0932\u0917\u093e\u0924\u093e\u0930 \u0905\u092d\u094d\u092f\u093e\u0938 \u0906\u092a\u0915\u0947 \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0947 \u0927\u094d\u092f\u093e\u0928, \u092a\u0922\u093c\u093e\u0908 \u092f\u093e \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u092c\u0941\u0926\u094d\u0927\u093f \u0915\u094b \u092c\u0947\u0939\u0924\u0930 \u092c\u0928\u093e \u0926\u0947\u0924\u093e \u0939\u0948 \u2014 \u0907\u0938 \u0924\u0930\u0939 \u0915\u0947 \u0905\u092d\u094d\u092f\u093e\u0938 \u0938\u0947 \u0935\u094d\u092f\u093e\u092a\u0915 '\u0938\u094d\u0925\u093e\u0928\u093e\u0902\u0924\u0930\u0923' \u091c\u093c\u094d\u092f\u093e\u0926\u093e\u0924\u0930 \u0905\u092a\u094d\u0930\u092e\u093e\u0923\u093f\u0924 \u0939\u0948, \u0914\u0930 \u0907\u0938\u0947 \u0927\u094d\u092f\u093e\u0928 \u0915\u094b \u0928\u093e\u092a\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u092c\u0928\u093e\u092f\u093e \u0917\u092f\u093e \u0925\u093e, \u0909\u0938\u0947 \u092c\u0922\u093c\u093e\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0928\u0939\u0940\u0902\u0964 \u0938\u0941\u0927\u093e\u0930 \u0915\u094b \u092e\u0941\u0916\u094d\u092f\u0924\u0903 \u0907\u0938\u0940 \u0916\u093e\u0938 \u0915\u093e\u0930\u094d\u092f \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b\u0928\u0947 \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u0932\u0947\u0902\u0964",rec:"\u0905\u092a\u0928\u0940 \u0928\u093f\u0917\u093e\u0939 \u092c\u0940\u091a \u0915\u0947 \u092c\u093f\u0902\u0926\u0941 \u0938\u0947 \u091a\u093f\u092a\u0915\u093e\u090f \u0930\u0916\u0947\u0902 \u0914\u0930 \u0938\u093f\u0930\u094d\u092b\u093c \u0905\u092a\u0928\u093e \u0927\u094d\u092f\u093e\u0928 \u0939\u093f\u0932\u093e\u090f\u0901 \u2014 \u0905\u0917\u0930 \u0906\u092a\u0915\u0940 \u0906\u0901\u0916\u0947\u0902 \u0938\u0902\u0915\u0947\u0924 \u0915\u0940 \u0913\u0930 \u0916\u093f\u0938\u0915\u0924\u0940 \u092a\u0915\u0921\u093c \u092e\u0947\u0902 \u0906\u090f\u0901, \u0924\u094b \u0930\u092b\u093c\u094d\u0924\u093e\u0930 \u0918\u091f\u093e\u090f\u0901 \u0914\u0930 \u092b\u093f\u0930 \u0938\u0947 \u091c\u092e \u091c\u093e\u090f\u0901\u0964",faq:[["\u0915\u094d\u092f\u093e \u092e\u0941\u091d\u0947 \u0938\u0902\u0915\u0947\u0924 \u0915\u0940 \u0913\u0930 \u0926\u0947\u0916\u0928\u0947 \u0915\u0940 \u0907\u091c\u093e\u091c\u093c\u0924 \u0939\u0948?","\u0928\u0939\u0940\u0902 \u2014 \u092a\u0942\u0930\u093e \u092e\u0915\u093c\u0938\u0926 \u092f\u0939\u0940 \u0939\u0948 \u0915\u093f \u0906\u0901\u0916\u0947\u0902 \u092c\u0940\u091a \u092e\u0947\u0902 \u091f\u093f\u0915\u093e\u090f \u0930\u0916\u0924\u0947 \u0939\u0941\u090f \u0927\u094d\u092f\u093e\u0928 \u0915\u094b \u0916\u093f\u0938\u0915\u093e\u092f\u093e \u091c\u093e\u090f\u0964 \u0906\u0901\u0916\u0947\u0902 \u0939\u093f\u0932\u093e\u0928\u0947 \u0938\u0947 \u092f\u0939 \u090f\u0915 \u0905\u0932\u0917, \u0906\u0938\u093e\u0928 \u0915\u093e\u0930\u094d\u092f \u092c\u0928 \u091c\u093e\u0924\u093e \u0939\u0948\u0964"],["\u0915\u092d\u0940-\u0915\u092d\u0940 \u0920\u0940\u0915 \u0935\u0939\u0940\u0902 \u092e\u0948\u0902 \u0927\u0940\u092e\u093e \u0915\u094d\u092f\u094b\u0902 \u092a\u0921\u093c \u091c\u093e\u0924\u093e \u0939\u0942\u0901 \u091c\u0939\u093e\u0901 \u0938\u0902\u0915\u0947\u0924 \u0928\u0947 \u0907\u0936\u093e\u0930\u093e \u0915\u093f\u092f\u093e \u0925\u093e?","\u0905\u0917\u0930 \u0938\u0902\u0915\u0947\u0924 \u0914\u0930 \u0932\u0915\u094d\u0937\u094d\u092f \u0915\u0947 \u092c\u0940\u091a \u0915\u093e\u092b\u093c\u0940 \u0938\u092e\u092f \u092c\u0940\u0924 \u091c\u093e\u090f, \u0924\u094b \u0927\u094d\u092f\u093e\u0928 \u0909\u0938 \u092a\u0939\u0932\u0947-\u0938\u0947-\u091c\u093e\u0901\u091a\u0940 \u091c\u0917\u0939 \u0938\u0947 \u0926\u0942\u0930 \u0927\u0915\u0947\u0932 \u0926\u093f\u092f\u093e \u091c\u093e\u0924\u093e \u0939\u0948\u0964 \u0907\u0938 \u0927\u0940\u092e\u0947\u092a\u0928 \u0915\u094b inhibition of return \u0915\u0939\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u092f\u0939 \u090f\u0915 \u0938\u093e\u092e\u093e\u0928\u094d\u092f, \u0905\u091a\u094d\u091b\u0940 \u0924\u0930\u0939 \u092a\u094d\u0930\u0932\u0947\u0916\u093f\u0924 \u092a\u094d\u0930\u092d\u093e\u0935 \u0939\u0948\u0964"],["\u0915\u094d\u092f\u093e \u0907\u0938\u0938\u0947 \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0940 \u091c\u093c\u093f\u0902\u0926\u0917\u0940 \u092e\u0947\u0902 \u092e\u0947\u0930\u093e \u0927\u094d\u092f\u093e\u0928 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0915\u0947\u0902\u0926\u094d\u0930\u093f\u0924 \u0939\u094b\u0917\u093e?","\u092f\u0939 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0922\u0902\u0917 \u0938\u0947 \u0906\u092a\u0915\u094b \u0907\u0938 \u0915\u093e\u0930\u094d\u092f \u092e\u0947\u0902 \u0924\u0947\u091c\u093c \u092c\u0928\u093e \u0926\u0947\u0924\u093e \u0939\u0948, \u092a\u0930 \u0907\u0938\u0915\u093e \u092b\u093c\u093e\u092f\u0926\u093e \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0940 \u090f\u0915\u093e\u0917\u094d\u0930\u0924\u093e \u092f\u093e \u092a\u0922\u093c\u093e\u0908 \u0924\u0915 \u092b\u0948\u0932\u0928\u0947 \u0915\u0947 \u0938\u092c\u0942\u0924 \u0915\u092e\u091c\u093c\u094b\u0930 \u0939\u0948\u0902\u0964 \u0907\u0938\u0947 \u090f\u0915 \u0938\u091f\u0940\u0915 \u0927\u094d\u092f\u093e\u0928-\u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0947 \u0924\u094c\u0930 \u092a\u0930 \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0915\u0930\u0947\u0902, \u0939\u0930 \u092e\u0930\u094d\u091c\u093c \u0915\u0940 \u0926\u0935\u093e \u0915\u0947 \u0924\u094c\u0930 \u092a\u0930 \u0928\u0939\u0940\u0902\u0964"]],variants:"\u0906\u092e \u092c\u0926\u0932\u093e\u0935\u094b\u0902 \u092e\u0947\u0902 \u0936\u093e\u092e\u093f\u0932 \u0939\u0948\u0902: \u090f\u0928\u094d\u0921\u094b\u091c\u0947\u0928\u0938 \u0938\u0902\u0915\u0947\u0924 (\u092c\u0940\u091a \u092e\u0947\u0902 \u092c\u0928\u093e \u0924\u0940\u0930 \u092f\u093e \u091a\u093f\u0939\u094d\u0928 \u091c\u093f\u0938\u0915\u093e \u0906\u092a \u0905\u0930\u094d\u0925 \u0932\u0917\u093e\u0924\u0947 \u0939\u0948\u0902) \u092c\u0928\u093e\u092e \u090f\u0915\u094d\u0938\u094b\u091c\u0947\u0928\u0938 \u0938\u0902\u0915\u0947\u0924 (\u0915\u093f\u0928\u093e\u0930\u0947 \u0915\u0940 \u091a\u092e\u0915 \u091c\u094b \u0905\u092a\u0928\u0947-\u0906\u092a \u0927\u094d\u092f\u093e\u0928 \u0916\u0940\u0902\u091a \u0932\u0947\u0924\u0940 \u0939\u0948); facilitation \u092c\u0928\u093e\u092e inhibition of return \u0915\u094b \u0909\u091c\u093e\u0917\u0930 \u0915\u0930\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0938\u0902\u0915\u0947\u0924 \u0914\u0930 \u0932\u0915\u094d\u0937\u094d\u092f \u0915\u0947 \u092c\u0940\u091a \u0915\u0940 \u0926\u0947\u0930\u0940 \u092c\u0926\u0932\u0928\u093e; \u0938\u0902\u0915\u0947\u0924 \u0915\u093f\u0924\u0928\u0940 \u092c\u093e\u0930 \u0938\u0939\u0940 \u0939\u094b\u0924\u093e \u0939\u0948 \u0907\u0938\u0947 \u0918\u091f\u093e\u0928\u093e-\u092c\u0922\u093c\u093e\u0928\u093e; \u0914\u0930 \u092d\u0947\u0926 \u0915\u0930\u0928\u0947 \u0935\u093e\u0932\u0947 \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u091c\u0939\u093e\u0901 \u0906\u092a\u0915\u094b \u0932\u0915\u094d\u0937\u094d\u092f \u0915\u094b \u092e\u0939\u091c\u093c \u092d\u093e\u0901\u092a\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u092a\u0939\u091a\u093e\u0928\u0928\u093e \u092a\u0921\u093c\u0924\u093e \u0939\u0948\u0964"},zh:{about:"\u5c4f\u5e55\u4e00\u4fa7\u4f1a\u77ed\u6682\u95ea\u8fc7\u4e00\u4e2a\u6807\u8bb0\u6216\u6307\u793a\uff0c\u968f\u540e\u76ee\u6807\u5728\u67d0\u5904\u51fa\u73b0\uff0c\u4f60\u8981\u5c3d\u53ef\u80fd\u5feb\u5730\u5bf9\u5b83\u505a\u51fa\u53cd\u5e94\u3002\u591a\u6570\u65f6\u5019\u63d0\u793a\u4f1a\u6307\u5411\u76ee\u6807\u771f\u6b63\u51fa\u73b0\u7684\u4f4d\u7f6e\uff08\u6709\u6548\u63d0\u793a\uff09\uff0c\u4f46\u6709\u65f6\u5b83\u4f1a\u8bef\u5bfc\u4f60\uff08\u65e0\u6548\u63d0\u793a\uff09\u2014\u2014\u4f60\u5728\u5feb\u3001\u6162\u4e24\u79cd\u53cd\u5e94\u4e4b\u95f4\u7684\u5dee\u8ddd\uff0c\u6b63\u662f\u6574\u4e2a\u7ec3\u4e60\u7684\u8981\u70b9\u6240\u5728\u3002",benefit:"\u5b83\u8bad\u7ec3\u7684\u662f\u9690\u853d\u7a7a\u95f4\u6ce8\u610f\uff1a\u5728\u4e0d\u79fb\u52a8\u773c\u775b\u7684\u60c5\u51b5\u4e0b\uff0c\u628a\u5fc3\u7406\u300c\u805a\u5149\u706f\u300d\u8f6c\u79fb\u5230\u67d0\u4e2a\u4f4d\u7f6e\u3001\u9501\u5b9a\u4e00\u4e2a\u6709\u7528\u63d0\u793a\uff0c\u4ee5\u53ca\u5f53\u63d0\u793a\u51fa\u9519\u65f6\u53ca\u65f6\u8131\u79bb\u5e76\u91cd\u65b0\u6307\u5411\u7684\u80fd\u529b\u3002\u7b80\u800c\u8a00\u4e4b\uff0c\u5b83\u6253\u78e8\u7684\u662f\u4f60\u5728\u89c6\u91ce\u8303\u56f4\u5185\u5206\u914d\u6ce8\u610f\u7684\u5feb\u6162\u4e0e\u7075\u6d3b\u5ea6\u3002",history:"\u5b83\u6e90\u81ea\u8ba4\u77e5\u5fc3\u7406\u5b66\u5728 1970 \u5e74\u4ee3\u672b\u628a\u6ce8\u610f\u529b\u4e0e\u773c\u52a8\u5206\u5f00\u6d4b\u91cf\u7684\u5c1d\u8bd5\u3002Michael Posner 1980 \u5e74\u7684\u8bba\u6587\u53d1\u8868\u540e\uff0c\u5b83\u6210\u4e3a\u8be5\u9886\u57df\u88ab\u590d\u73b0\u6700\u591a\u7684\u5b9e\u9a8c\u8303\u5f0f\u4e4b\u4e00\uff0c\u8fdb\u5165\u795e\u7ecf\u5fc3\u7406\u5b66\u8bca\u5ba4\uff08\u7528\u4e8e\u8bc4\u4f30\u5355\u4fa7\u7a7a\u95f4\u5ffd\u89c6\u3001ADHD \u4ee5\u53ca\u5c40\u7076\u6027\u8111\u635f\u4f24\u7684\u5f71\u54cd\uff09\uff0c\u540e\u6765\u53c8\u884d\u751f\u51fa\u6570\u4e0d\u6e05\u7684\u5b9e\u9a8c\u5ba4\u7248\u672c\u548c\u5728\u7ebf\u7248\u672c\u3002",creator:"\u7531\u7f8e\u56fd\u5fc3\u7406\u5b66\u5bb6 Michael I. Posner \u521b\u5236\uff0c\u4ed6\u5728 1980 \u5e74\u7684\u8bba\u6587\u300aOrienting of Attention\u300b\uff08\u300aQuarterly Journal of Experimental Psychology\u300b\uff09\u4e2d\u63d0\u51fa\u4e86\u5b83\u3002\u53cd\u5c04\u6027\u53d8\u4f53\u4ee5\u53ca\u300c\u8fd4\u56de\u6291\u5236\u300d\u6548\u5e94\uff0c\u5219\u7531 Posner \u548c Yoav Cohen \u4e8e 1984 \u5e74\u63cf\u8ff0\u3002",methods:"\u628a\u76ee\u5149\u56fa\u5b9a\u5728\u5c4f\u5e55\u4e2d\u592e\uff0c\u5fcd\u4f4f\u671d\u63d0\u793a\u65b9\u5411\u779f\u8fc7\u53bb\u7684\u51b2\u52a8\u2014\u2014\u8fd9\u9879\u6280\u80fd\u7ec3\u7684\u662f\u79fb\u52a8\u6ce8\u610f\uff0c\u800c\u4e0d\u662f\u79fb\u52a8\u773c\u775b\u3002\u4e24\u79cd\u63d0\u793a\u90fd\u8981\u7ec3\uff1a\u4e00\u79cd\u662f\u4f60\u4e3b\u52a8\u53bb\u8ddf\u968f\u7684\u4e2d\u592e\u7bad\u5934\uff08\u5185\u6e90\u6027\uff09\uff0c\u4e00\u79cd\u662f\u81ea\u52a8\u6293\u4f4f\u4f60\u7684\u5916\u5468\u95ea\u5149\uff08\u5916\u6e90\u6027\uff09\u3002\u8981\u7279\u522b\u7559\u610f\u65e0\u6548\u8bd5\u6b21\uff0c\u56e0\u4e3a\u5b66\u4f1a\u653e\u6389\u9519\u8bef\u63d0\u793a\u3001\u91cd\u65b0\u7784\u51c6\uff0c\u6b63\u662f\u5927\u90e8\u5206\u6536\u76ca\u7684\u6765\u6e90\u3002",duration:"\u77ed\u65f6\u6bb5\u7ec3\u4e60\u6548\u679c\u6700\u597d\uff1a\u5927\u7ea6 5 \u5230 10 \u5206\u949f\uff0c\u6bcf\u5468\u51e0\u6b21\u3002\u5b83\u53c8\u5feb\u53c8\u91cd\u590d\uff0c\u6ce8\u610f\u529b\u5f88\u5feb\u5c31\u4f1a\u6da3\u6563\u2014\u2014\u5728\u5b83\u53d8\u5f97\u673a\u68b0\u4e4b\u524d\u5c31\u505c\uff0c\u800c\u4e0d\u662f\u786c\u71ac\u957f\u6bb5\u3002",research:"\u5df2\u88ab\u7a33\u56fa\u786e\u7acb\u7684\u662f\u8fd9\u4e2a\u57fa\u672c\u6548\u5e94\u672c\u8eab\uff1a\u4eba\u4eec\u5bf9\u6709\u6548\u63d0\u793a\u4f4d\u7f6e\u53cd\u5e94\u66f4\u5feb\u3001\u5bf9\u65e0\u6548\u63d0\u793a\u4f4d\u7f6e\u53cd\u5e94\u66f4\u6162\uff0c\u800c\u5f53\u63d0\u793a\u4e0e\u76ee\u6807\u7684\u95f4\u9694\u62c9\u957f\u65f6\uff0c\u8fd9\u79cd\u4f18\u52bf\u4f1a\u53cd\u8f6c\u4e3a\u300c\u8fd4\u56de\u6291\u5236\u300d\u3002\u8fd9\u4e9b\u53d1\u73b0\u53ef\u4ee5\u7a33\u5065\u590d\u73b0\uff0c\u8be5\u4efb\u52a1\u4e5f\u662f\u516c\u8ba4\u53ef\u9760\u7684\u5b9e\u9a8c\u5ba4\u6d4b\u91cf\u3002\u8981\u5f31\u5f97\u591a\u7684\uff0c\u662f\u300c\u53cd\u590d\u7ec3\u5b83\u80fd\u8ba9\u4f60\u65e5\u5e38\u7684\u6ce8\u610f\u529b\u3001\u9605\u8bfb\u6216\u4e00\u822c\u667a\u529b\u53d8\u597d\u300d\u8fd9\u79cd\u8bf4\u6cd5\u2014\u2014\u8fd9\u7c7b\u7ec3\u4e60\u7684\u5e7f\u6cdb\u300c\u8fc1\u79fb\u300d\u57fa\u672c\u672a\u88ab\u8bc1\u5b9e\uff0c\u5b83\u88ab\u8bbe\u8ba1\u51fa\u6765\u662f\u4e3a\u4e86\u6d4b\u91cf\u6ce8\u610f\uff0c\u800c\u975e\u63d0\u5347\u6ce8\u610f\u3002\u628a\u8fdb\u6b65\u4e3b\u8981\u770b\u4f5c\u662f\u4f60\u5728\u8fd9\u9879\u5177\u4f53\u4efb\u52a1\u4e0a\u53d8\u5f97\u66f4\u597d\u4e86\u3002",rec:"\u628a\u89c6\u7ebf\u7262\u7262\u9489\u5728\u4e2d\u592e\u90a3\u4e2a\u70b9\u4e0a\uff0c\u53ea\u79fb\u52a8\u4f60\u7684\u6ce8\u610f\u529b\u2014\u2014\u4e00\u65e6\u53d1\u73b0\u773c\u775b\u98d8\u5411\u63d0\u793a\uff0c\u5c31\u653e\u6162\u8282\u594f\u3001\u91cd\u65b0\u5f52\u4f4d\u3002",faq:[["\u6211\u53ef\u4ee5\u76ef\u7740\u63d0\u793a\u770b\u5417\uff1f","\u4e0d\u884c\u2014\u2014\u6574\u4e2a\u8981\u70b9\u5c31\u662f\u5728\u773c\u775b\u4fdd\u6301\u6ce8\u89c6\u4e2d\u592e\u7684\u540c\u65f6\u8f6c\u79fb\u6ce8\u610f\u3002\u79fb\u52a8\u773c\u775b\u4f1a\u628a\u5b83\u53d8\u6210\u53e6\u4e00\u79cd\u66f4\u5bb9\u6613\u7684\u4efb\u52a1\u3002"],["\u4e3a\u4ec0\u4e48\u6709\u65f6\u6211\u5728\u63d0\u793a\u6240\u6307\u7684\u4f4d\u7f6e\u53cd\u800c\u66f4\u6162\uff1f","\u5982\u679c\u63d0\u793a\u548c\u76ee\u6807\u4e4b\u95f4\u7ecf\u8fc7\u7684\u65f6\u95f4\u8db3\u591f\u957f\uff0c\u6ce8\u610f\u4f1a\u88ab\u63a8\u79bb\u90a3\u4e2a\u5df2\u7ecf\u67e5\u770b\u8fc7\u7684\u4f4d\u7f6e\u3002\u8fd9\u79cd\u53d8\u6162\u53eb\u505a\u8fd4\u56de\u6291\u5236\uff0c\u662f\u4e00\u79cd\u6b63\u5e38\u4e14\u6709\u5145\u5206\u8bb0\u5f55\u7684\u6548\u5e94\u3002"],["\u8fd9\u4f1a\u8ba9\u6211\u5728\u65e5\u5e38\u751f\u6d3b\u4e2d\u66f4\u4e13\u6ce8\u5417\uff1f","\u5b83\u80fd\u53ef\u9760\u5730\u8ba9\u4f60\u5728\u8fd9\u9879\u4efb\u52a1\u4e0a\u66f4\u5feb\uff0c\u4f46\u300c\u597d\u5904\u4f1a\u6269\u6563\u5230\u65e5\u5e38\u4e13\u6ce8\u6216\u5b66\u4e60\u300d\u7684\u8bc1\u636e\u5f88\u5f31\u3002\u628a\u5b83\u5f53\u4f5c\u4e00\u9879\u7cbe\u786e\u7684\u6ce8\u610f\u529b\u7ec3\u4e60\uff0c\u800c\u4e0d\u662f\u5305\u6cbb\u767e\u75c5\u7684\u7075\u836f\u3002"]],variants:"\u5e38\u89c1\u53d8\u4f53\u5305\u62ec\uff1a\u5185\u6e90\u6027\u63d0\u793a\uff08\u4f60\u9700\u8981\u53bb\u89e3\u8bfb\u7684\u4e2d\u592e\u7bad\u5934\u6216\u7b26\u53f7\uff09\u5bf9\u5916\u6e90\u6027\u63d0\u793a\uff08\u81ea\u52a8\u7275\u5f15\u6ce8\u610f\u7684\u5916\u5468\u95ea\u5149\uff09\uff1b\u6539\u53d8\u63d0\u793a\u4e0e\u76ee\u6807\u4e4b\u95f4\u7684\u5ef6\u8fdf\uff0c\u4ee5\u66b4\u9732\u6613\u5316\u6548\u5e94\u8fd8\u662f\u8fd4\u56de\u6291\u5236\uff1b\u6539\u53d8\u63d0\u793a\u6709\u6548\u7684\u9891\u7387\uff1b\u4ee5\u53ca\u8fa8\u522b\u7248\uff0c\u8981\u6c42\u4f60\u8bc6\u522b\u76ee\u6807\u800c\u4e0d\u53ea\u662f\u53d1\u73b0\u5b83\u3002"}},prl:{ru:{about:"PRL \u2014 \u044d\u0442\u043e \u0437\u0430\u0434\u0430\u0447\u0430 \u043d\u0430 \u0432\u0435\u0440\u043e\u044f\u0442\u043d\u043e\u0441\u0442\u043d\u043e\u0435 \u043e\u0431\u0443\u0447\u0435\u043d\u0438\u0435 \u0441 \u043f\u0435\u0440\u0435\u043c\u0435\u043d\u043e\u0439 \u043f\u0440\u0430\u0432\u0438\u043b\u0430. \u041d\u0430 \u043a\u0430\u0436\u0434\u043e\u043c \u0448\u0430\u0433\u0435 \u0432\u044b \u0432\u044b\u0431\u0438\u0440\u0430\u0435\u0442\u0435 \u043e\u0434\u0438\u043d \u0438\u0437 \u0434\u0432\u0443\u0445 \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u043e\u0432; \xab\u0445\u043e\u0440\u043e\u0448\u0438\u0439\xbb \u0432\u0430\u0440\u0438\u0430\u043d\u0442 \u043f\u0440\u0438\u043d\u043e\u0441\u0438\u0442 \u043d\u0430\u0433\u0440\u0430\u0434\u0443 \u0447\u0430\u0449\u0435 \u0434\u0440\u0443\u0433\u043e\u0433\u043e, \u043d\u043e \u043d\u0435 \u0432\u0441\u0435\u0433\u0434\u0430, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u043f\u0440\u0430\u0432\u0438\u043b\u044c\u043d\u044b\u0439 \u0432\u044b\u0431\u043e\u0440 \u043f\u0440\u0438\u0445\u043e\u0434\u0438\u0442\u0441\u044f \u043d\u0430\u0449\u0443\u043f\u044b\u0432\u0430\u0442\u044c \u043c\u0435\u0442\u043e\u0434\u043e\u043c \u043f\u0440\u043e\u0431 \u0438 \u043e\u0448\u0438\u0431\u043e\u043a. \u0411\u0435\u0437 \u043f\u0440\u0435\u0434\u0443\u043f\u0440\u0435\u0436\u0434\u0435\u043d\u0438\u044f \u043f\u0440\u0430\u0432\u0438\u043b\u043e \u043c\u0435\u043d\u044f\u0435\u0442\u0441\u044f, \u0438 \u0432\u044b\u0433\u043e\u0434\u043d\u044b\u043c \u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u0441\u044f \u0432\u0442\u043e\u0440\u043e\u0439 \u0432\u0430\u0440\u0438\u0430\u043d\u0442 \u2014 \u0437\u0430\u0434\u0430\u0447\u0430 \u0432 \u0442\u043e\u043c, \u0447\u0442\u043e\u0431\u044b \u0432\u043e\u0432\u0440\u0435\u043c\u044f \u044d\u0442\u043e \u0437\u0430\u043c\u0435\u0442\u0438\u0442\u044c \u0438 \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0438\u0442\u044c\u0441\u044f, \u0430 \u043d\u0435 \u0446\u0435\u043f\u043b\u044f\u0442\u044c\u0441\u044f \u0437\u0430 \u0442\u043e, \u0447\u0442\u043e \u0440\u0430\u0431\u043e\u0442\u0430\u043b\u043e \u0440\u0430\u043d\u044c\u0448\u0435.",benefit:"\u0422\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u0433\u0438\u0431\u043a\u043e\u0441\u0442\u044c \u043c\u044b\u0448\u043b\u0435\u043d\u0438\u044f \u0438 \u043e\u0431\u0443\u0447\u0435\u043d\u0438\u0435 \u043f\u043e \u043e\u0431\u0440\u0430\u0442\u043d\u043e\u0439 \u0441\u0432\u044f\u0437\u0438 \u0432 \u0443\u0441\u043b\u043e\u0432\u0438\u044f\u0445 \u043d\u0435\u043e\u043f\u0440\u0435\u0434\u0435\u043b\u0451\u043d\u043d\u043e\u0441\u0442\u0438: \u0434\u0435\u0440\u0436\u0430\u0442\u044c\u0441\u044f \u043f\u0440\u0430\u0432\u0438\u043b\u0430, \u043f\u043e\u043a\u0430 \u043e\u043d\u043e \u043f\u0440\u0438\u043d\u043e\u0441\u0438\u0442 \u0432\u044b\u0438\u0433\u0440\u044b\u0448, \u043e\u0442\u043b\u0438\u0447\u0430\u0442\u044c \u043d\u0430\u0441\u0442\u043e\u044f\u0449\u0443\u044e \u0441\u043c\u0435\u043d\u0443 \u043f\u0440\u0430\u0432\u0438\u043b\u0430 \u043e\u0442 \u043f\u043e\u043b\u043e\u0441\u044b \u043d\u0435\u0432\u0435\u0437\u0435\u043d\u0438\u044f \u0438 \u043c\u0435\u043d\u044f\u0442\u044c \u0432\u044b\u0431\u043e\u0440, \u043d\u0435 \u0434\u0451\u0440\u0433\u0430\u044f\u0441\u044c \u0438\u0437-\u0437\u0430 \u0435\u0434\u0438\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0433\u043e \u043e\u0431\u043c\u0430\u043d\u0447\u0438\u0432\u043e\u0433\u043e \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442\u0430.",history:"\u0418\u0434\u0435\u044f \u0432\u044b\u0440\u043e\u0441\u043b\u0430 \u0438\u0437 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u0439 \u043e\u0431\u0443\u0447\u0435\u043d\u0438\u044f \u0436\u0438\u0432\u043e\u0442\u043d\u044b\u0445 \u0441\u0435\u0440\u0435\u0434\u0438\u043d\u044b XX \u0432\u0435\u043a\u0430: \u0436\u0438\u0432\u043e\u0442\u043d\u043e\u0435 \u043e\u0431\u0443\u0447\u0430\u043b\u0438 \u043f\u0440\u043e\u0441\u0442\u043e\u043c\u0443 \u0440\u0430\u0437\u043b\u0438\u0447\u0435\u043d\u0438\u044e, \u0430 \u0437\u0430\u0442\u0435\u043c \u043c\u0435\u043d\u044f\u043b\u0438 \u043c\u0435\u0441\u0442\u0430\u043c\u0438 \u0432\u043e\u0437\u043d\u0430\u0433\u0440\u0430\u0436\u0434\u0430\u0435\u043c\u044b\u0435 \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u044b \u0438 \u0441\u043c\u043e\u0442\u0440\u0435\u043b\u0438, \u043a\u0430\u043a \u0431\u044b\u0441\u0442\u0440\u043e \u043e\u043d\u043e \u043f\u0435\u0440\u0435\u0443\u0447\u0438\u0442\u0441\u044f. \u0412\u0435\u0440\u043e\u044f\u0442\u043d\u043e\u0441\u0442\u043d\u0430\u044f \u0432\u0435\u0440\u0441\u0438\u044f \u0434\u043b\u044f \u043b\u044e\u0434\u0435\u0439 \u043e\u0444\u043e\u0440\u043c\u0438\u043b\u0430\u0441\u044c \u0432 \u043a\u043e\u0433\u043d\u0438\u0442\u0438\u0432\u043d\u043e\u0439 \u043d\u0435\u0439\u0440\u043e\u043d\u0430\u0443\u043a\u0435 \u0432 \u043d\u0430\u0447\u0430\u043b\u0435 2000-\u0445, \u043a\u043e\u0433\u0434\u0430 \u043a \u043e\u0431\u0440\u0430\u0442\u043d\u043e\u0439 \u0441\u0432\u044f\u0437\u0438 \u0434\u043e\u0431\u0430\u0432\u0438\u043b\u0438 \xab\u0448\u0443\u043c\xbb, \u0447\u0442\u043e\u0431\u044b \u0431\u043b\u0438\u0436\u0435 \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u0435\u0441\u0442\u0438 \u043d\u0435\u043e\u043f\u0440\u0435\u0434\u0435\u043b\u0451\u043d\u043d\u043e\u0441\u0442\u044c \u0440\u0435\u0430\u043b\u044c\u043d\u043e\u0439 \u0436\u0438\u0437\u043d\u0438 \u0438 \u043f\u0440\u043e\u0432\u0435\u0440\u0438\u0442\u044c, \u043a\u0430\u043a \u043c\u043e\u0437\u0433 \u0441\u043f\u0440\u0430\u0432\u043b\u044f\u0435\u0442\u0441\u044f \u0441 \u043c\u0435\u043d\u044f\u044e\u0449\u0438\u043c\u0438\u0441\u044f \u043f\u0440\u0430\u0432\u0438\u043b\u0430\u043c\u0438.",creator:"\u0415\u0434\u0438\u043d\u043e\u0433\u043e \u0438\u0437\u043e\u0431\u0440\u0435\u0442\u0430\u0442\u0435\u043b\u044f \u043d\u0435\u0442. \u0420\u0435\u0432\u0435\u0440\u0441\u0438\u0432\u043d\u043e\u0435 \u043e\u0431\u0443\u0447\u0435\u043d\u0438\u0435 \u043f\u0440\u0438\u0448\u043b\u043e \u0438\u0437 \u0431\u0438\u0445\u0435\u0432\u0438\u043e\u0440\u0438\u0441\u0442\u0441\u043a\u043e\u0439 \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u0438 \u043e\u043f\u044b\u0442\u043e\u0432 \u0441\u043e \u0441\u043c\u0435\u043d\u043e\u0439 \u0440\u0430\u0437\u043b\u0438\u0447\u0435\u043d\u0438\u044f 1940\u20131950-\u0445 \u0433\u043e\u0434\u043e\u0432, \u0441\u0432\u044f\u0437\u0430\u043d\u043d\u043e\u0439 \u0441 \u0442\u0430\u043a\u0438\u043c\u0438 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u044f\u043c\u0438, \u043a\u0430\u043a \u0413\u0430\u0440\u0440\u0438 \u0425\u0430\u0440\u043b\u043e\u0443, \u0441\u0443\u043f\u0440\u0443\u0433\u0438 \u041a\u0435\u043d\u0434\u043b\u0435\u0440 \u0438 \u041d. \u0414\u0436. \u041c\u0430\u043a\u0438\u043d\u0442\u043e\u0448. \u0421\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u0443\u044e \u0432\u0435\u0440\u043e\u044f\u0442\u043d\u043e\u0441\u0442\u043d\u0443\u044e \u0432\u0435\u0440\u0441\u0438\u044e \u0434\u043b\u044f \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u0439 \u043c\u043e\u0437\u0433\u0430 \u0447\u0435\u043b\u043e\u0432\u0435\u043a\u0430 \u043e\u0431\u044b\u0447\u043d\u043e \u0441\u0432\u044f\u0437\u044b\u0432\u0430\u044e\u0442 \u0441 \u0440\u0430\u0431\u043e\u0442\u043e\u0439 \u0420\u043e\u0448\u0430\u043d \u041a\u0443\u043b\u0441, \u041b\u044e\u043a\u0430 \u041a\u043b\u0430\u0440\u043a\u0430 \u0438 \u043a\u043e\u043b\u043b\u0435\u0433 \u0438\u0437 \u041a\u0435\u043c\u0431\u0440\u0438\u0434\u0436\u0430 \u043e\u043a\u043e\u043b\u043e 2002 \u0433\u043e\u0434\u0430, \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u043e\u043f\u0438\u0440\u0430\u043b\u0438\u0441\u044c \u043d\u0430 \u044d\u0442\u0443 \u0434\u0430\u0432\u043d\u044e\u044e \u043b\u0438\u043d\u0438\u044e, \u0430 \u043d\u0435 \u043e\u0441\u043d\u043e\u0432\u0430\u043b\u0438 \u0435\u0451.",methods:"\u0412\u043e\u0441\u043f\u0440\u0438\u043d\u0438\u043c\u0430\u0439\u0442\u0435 \u043e\u0434\u0438\u043d \u043f\u0440\u043e\u043c\u0430\u0445 \u043a\u0430\u043a \u0448\u0443\u043c, \u0430 \u043d\u0435 \u043a\u0430\u043a \u0434\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432\u043e: \u0432\u044b\u0432\u043e\u0434 \u043e \u0441\u043c\u0435\u043d\u0435 \u043f\u0440\u0430\u0432\u0438\u043b\u0430 \u0434\u0435\u043b\u0430\u0439\u0442\u0435 \u043b\u0438\u0448\u044c \u043f\u043e\u0441\u043b\u0435 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u0438\u0445 \u043d\u0435\u0443\u0434\u0430\u0447 \u043f\u043e\u0434\u0440\u044f\u0434 \u043f\u043e \u0442\u043e\u043c\u0443 \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u0443, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u0441\u0447\u0438\u0442\u0430\u043b\u0438 \u043b\u0443\u0447\u0448\u0438\u043c. \u0414\u0435\u0440\u0436\u0438\u0442\u0435 \u0432 \u0433\u043e\u043b\u043e\u0432\u0435 \u043e\u0431\u0449\u0443\u044e \u043a\u0430\u0440\u0442\u0438\u043d\u0443 \u043f\u043e\u0441\u043b\u0435\u0434\u043d\u0438\u0445 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442\u043e\u0432, \u0430 \u043d\u0435 \u0440\u0435\u0430\u0433\u0438\u0440\u0443\u0439\u0442\u0435 \u043d\u0430 \u0441\u0430\u043c\u044b\u0439 \u043f\u043e\u0441\u043b\u0435\u0434\u043d\u0438\u0439 \u0448\u0430\u0433, \u0438, \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0438\u0432\u0448\u0438\u0441\u044c, \u0434\u0430\u0439\u0442\u0435 \u043d\u043e\u0432\u043e\u043c\u0443 \u0432\u044b\u0431\u043e\u0440\u0443 \u0434\u043e\u0441\u0442\u0430\u0442\u043e\u0447\u043d\u043e \u043f\u043e\u043f\u044b\u0442\u043e\u043a, \u0447\u0442\u043e\u0431\u044b \u0443\u0431\u0435\u0434\u0438\u0442\u044c\u0441\u044f \u0432 \u043d\u0451\u043c, \u043f\u0440\u0435\u0436\u0434\u0435 \u0447\u0435\u043c \u0441\u043d\u043e\u0432\u0430 \u0441\u043e\u043c\u043d\u0435\u0432\u0430\u0442\u044c\u0441\u044f.",duration:"\u041b\u0443\u0447\u0448\u0435 \u0440\u0430\u0431\u043e\u0442\u0430\u044e\u0442 \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u0435 \u0440\u0435\u0433\u0443\u043b\u044f\u0440\u043d\u044b\u0435 \u043f\u043e\u0434\u0445\u043e\u0434\u044b: \u043f\u0440\u0438\u043c\u0435\u0440\u043d\u043e 5\u201310 \u043c\u0438\u043d\u0443\u0442 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0440\u0430\u0437 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e. \u0422\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442\u0441\u044f \u0431\u044b\u0441\u0442\u0440\u043e\u0435 \u043e\u0431\u043d\u043e\u0432\u043b\u0435\u043d\u0438\u0435 \u0440\u0435\u0448\u0435\u043d\u0438\u044f, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u0445 \u0437\u0430\u0445\u043e\u0434\u043e\u0432 \u043f\u043e\u043b\u0435\u0437\u043d\u0435\u0435 \u043e\u0434\u043d\u043e\u0433\u043e \u0434\u043e\u043b\u0433\u043e\u0433\u043e, \u043d\u0430 \u043a\u043e\u0442\u043e\u0440\u043e\u043c \u0443\u0441\u0442\u0430\u043b\u043e\u0441\u0442\u044c \u0434\u0435\u043b\u0430\u0435\u0442 \u0432\u0430\u0441 \u043b\u0438\u0431\u043e \u0441\u043b\u0438\u0448\u043a\u043e\u043c \u0434\u0451\u0440\u0433\u0430\u043d\u044b\u043c, \u043b\u0438\u0431\u043e \u0441\u043b\u0438\u0448\u043a\u043e\u043c \u0443\u043f\u0440\u044f\u043c\u044b\u043c.",research:"\u041d\u0430\u0434\u0451\u0436\u043d\u0435\u0435 \u0432\u0441\u0435\u0433\u043e \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043d\u043e \u043e\u0447\u0435\u0432\u0438\u0434\u043d\u043e\u0435: \u0441 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u043e\u0439 \u0432\u044b \u043b\u0443\u0447\u0448\u0435 \u0441\u043f\u0440\u0430\u0432\u043b\u044f\u0435\u0442\u0435\u0441\u044c \u0441 \u0441\u0430\u043c\u043e\u0439 \u0437\u0430\u0434\u0430\u0447\u0435\u0439 \u0438 \u0442\u043e\u0447\u043d\u0435\u0435 \u043e\u0442\u043b\u0438\u0447\u0430\u0435\u0442\u0435 \u0440\u0435\u0430\u043b\u044c\u043d\u0443\u044e \u0441\u043c\u0435\u043d\u0443 \u043f\u0440\u0430\u0432\u0438\u043b\u0430 \u043e\u0442 \u0441\u043b\u0443\u0447\u0430\u0439\u043d\u043e\u0439 \u043f\u043e\u043b\u043e\u0441\u044b \u043d\u0435\u0443\u0434\u0430\u0447, \u0430 \u0441\u0430\u043c\u0430 \u0437\u0430\u0434\u0430\u0447\u0430 \u0441\u0442\u0430\u0431\u0438\u043b\u044c\u043d\u043e \u0443\u043b\u0430\u0432\u043b\u0438\u0432\u0430\u0435\u0442 \u0440\u0430\u0437\u043b\u0438\u0447\u0438\u044f \u0432 \u0433\u0438\u0431\u043a\u043e\u0441\u0442\u0438 \u043c\u0435\u0436\u0434\u0443 \u0433\u0440\u0443\u043f\u043f\u0430\u043c\u0438 \u0432 \u043a\u043b\u0438\u043d\u0438\u0447\u0435\u0441\u043a\u0438\u0445 \u0438 \u043d\u0435\u0439\u0440\u043e\u0431\u0438\u043e\u043b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u0438\u0445 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u044f\u0445. \u0423\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043d\u0438\u044f, \u0447\u0442\u043e \u0442\u0430\u043a\u0430\u044f \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0430 \u0448\u0438\u0440\u043e\u043a\u043e \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0438\u0442\u0441\u044f \u043d\u0430 \u043f\u043e\u0432\u0441\u0435\u0434\u043d\u0435\u0432\u043d\u044b\u0435 \u0440\u0435\u0448\u0435\u043d\u0438\u044f \u0438\u043b\u0438 \u043e\u0431\u0449\u0443\u044e \xab\u0433\u0438\u0431\u043a\u043e\u0441\u0442\u044c \u043c\u044b\u0448\u043b\u0435\u043d\u0438\u044f\xbb, \u0441\u043b\u0430\u0431\u044b \u0438 \u0441\u043f\u043e\u0440\u043d\u044b, \u0430 \u0432\u0441\u044f \u043e\u0431\u043b\u0430\u0441\u0442\u044c \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0438 \u043c\u043e\u0437\u0433\u0430 \u0434\u0430\u0451\u0442 \u043c\u0430\u043b\u043e \u043e\u0441\u043d\u043e\u0432\u0430\u043d\u0438\u0439 \u0436\u0434\u0430\u0442\u044c \u0434\u0430\u043b\u044c\u043d\u0435\u0433\u043e \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0430, \u0442\u0430\u043a \u0447\u0442\u043e \u043a \u0433\u0440\u043e\u043c\u043a\u0438\u043c \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f\u043c \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u0435\u0441\u044c \u0441 \u043e\u0441\u0442\u043e\u0440\u043e\u0436\u043d\u043e\u0441\u0442\u044c\u044e.",rec:"\u041f\u0440\u0435\u0436\u0434\u0435 \u0447\u0435\u043c \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0438\u0442\u044c\u0441\u044f, \u0441\u043f\u0440\u043e\u0441\u0438\u0442\u0435 \u0441\u0435\u0431\u044f: \u0432\u044b \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043b\u044c\u043d\u043e \u0432\u0438\u0434\u0438\u0442\u0435 \u0447\u0435\u0440\u0435\u0434\u0443 \u043d\u0435\u0443\u0434\u0430\u0447 \u0438\u043b\u0438 \u044d\u0442\u043e \u0432\u0441\u0435\u0433\u043e \u043e\u0434\u0438\u043d \u043d\u0435\u0432\u0435\u0437\u0443\u0447\u0438\u0439 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442 \u2014 \u0438 \u043c\u0435\u043d\u044f\u0439\u0442\u0435 \u0432\u044b\u0431\u043e\u0440 \u0442\u043e\u043b\u044c\u043a\u043e \u0442\u043e\u0433\u0434\u0430, \u043a\u043e\u0433\u0434\u0430 \u0434\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432 \u043d\u0430\u043a\u043e\u043f\u0438\u043b\u043e\u0441\u044c \u0434\u043e\u0441\u0442\u0430\u0442\u043e\u0447\u043d\u043e.",faq:[["\u041f\u043e\u0447\u0435\u043c\u0443 \u044f \u043f\u0440\u043e\u0438\u0433\u0440\u0430\u043b, \u0445\u043e\u0442\u044f \u0432\u044b\u0431\u0440\u0430\u043b \xab\u043f\u0440\u0430\u0432\u0438\u043b\u044c\u043d\u044b\u0439\xbb \u0432\u0430\u0440\u0438\u0430\u043d\u0442?","\u041f\u043e\u0442\u043e\u043c\u0443 \u0447\u0442\u043e \u0445\u043e\u0440\u043e\u0448\u0438\u0439 \u0432\u0430\u0440\u0438\u0430\u043d\u0442 \u043f\u0440\u0438\u043d\u043e\u0441\u0438\u0442 \u043d\u0430\u0433\u0440\u0430\u0434\u0443 \u0447\u0430\u0449\u0435, \u043d\u043e \u043d\u0435 \u043a\u0430\u0436\u0434\u044b\u0439 \u0440\u0430\u0437. \u041e\u0434\u0438\u043d \u043f\u0440\u043e\u0438\u0433\u0440\u044b\u0448 \u2014 \u044d\u0442\u043e \u0447\u0430\u0449\u0435 \u0432\u0441\u0435\u0433\u043e \u0448\u0443\u043c, \u0438 \u043f\u0440\u0430\u0432\u0438\u043b\u043e \u0432\u043e\u0432\u0441\u0435 \u043d\u0435 \u043e\u0431\u044f\u0437\u0430\u0442\u0435\u043b\u044c\u043d\u043e \u043f\u043e\u043c\u0435\u043d\u044f\u043b\u043e\u0441\u044c."],["\u041a\u0430\u043a \u043f\u043e\u043d\u044f\u0442\u044c, \u0447\u0442\u043e \u043f\u0440\u0430\u0432\u0438\u043b\u043e \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043b\u044c\u043d\u043e \u0441\u043c\u0435\u043d\u0438\u043b\u043e\u0441\u044c?","\u0418\u0449\u0438\u0442\u0435 \u0447\u0435\u0440\u0435\u0434\u0443 \u043f\u043b\u043e\u0445\u0438\u0445 \u0438\u0441\u0445\u043e\u0434\u043e\u0432 \u043f\u043e \u0442\u043e\u043c\u0443 \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u0443, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u0440\u0430\u043d\u044c\u0448\u0435 \u0440\u0430\u0431\u043e\u0442\u0430\u043b, \u0430 \u043d\u0435 \u043e\u0434\u0438\u043d \u043f\u0440\u043e\u043c\u0430\u0445. \u041a\u043e\u0433\u0434\u0430 \u043d\u0435\u0443\u0434\u0430\u0447\u0438 \u0438\u0434\u0443\u0442 \u043f\u043e\u0434\u0440\u044f\u0434 \u2014 \u044d\u0442\u043e \u0438 \u0435\u0441\u0442\u044c \u0441\u0438\u0433\u043d\u0430\u043b \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0430\u0442\u044c\u0441\u044f."],["\u0421\u0442\u0430\u043d\u0435\u0442 \u043b\u0438 \u043c\u043e\u0451 \u043c\u044b\u0448\u043b\u0435\u043d\u0438\u0435 \u0433\u0438\u0431\u0447\u0435 \u0432 \u0440\u0435\u0430\u043b\u044c\u043d\u043e\u0439 \u0436\u0438\u0437\u043d\u0438?","\u0412\u044b \u043d\u0430\u0432\u0435\u0440\u043d\u044f\u043a\u0430 \u0441\u0442\u0430\u043d\u0435\u0442\u0435 \u043b\u0443\u0447\u0448\u0435 \u0432 \u044d\u0442\u043e\u0439 \u0438 \u043f\u043e\u0445\u043e\u0436\u0438\u0445 \u0437\u0430\u0434\u0430\u0447\u0430\u0445. \u0428\u0438\u0440\u043e\u043a\u0438\u0439 \u043f\u0435\u0440\u0435\u043d\u043e\u0441 \u043d\u0430 \u043f\u043e\u0432\u0441\u0435\u0434\u043d\u0435\u0432\u043d\u044b\u0435 \u0440\u0435\u0448\u0435\u043d\u0438\u044f \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0451\u043d \u0441\u043b\u0430\u0431\u043e, \u0442\u0430\u043a \u0447\u0442\u043e \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0439\u0442\u0435\u0441\u044c \u0432 \u0443\u0434\u043e\u0432\u043e\u043b\u044c\u0441\u0442\u0432\u0438\u0435, \u043d\u043e \u043d\u0435 \u0440\u0430\u0441\u0441\u0447\u0438\u0442\u044b\u0432\u0430\u0439\u0442\u0435 \u043d\u0430 \u043f\u0435\u0440\u0435\u043c\u0435\u043d\u044b, \u043c\u0435\u043d\u044f\u044e\u0449\u0438\u0435 \u0436\u0438\u0437\u043d\u044c."]],variants:"\u0412\u0430\u0440\u0438\u0430\u043d\u0442\u044b \u043c\u0435\u043d\u044f\u044e\u0442 \u0441\u043b\u043e\u0436\u043d\u043e\u0441\u0442\u044c \u0437\u0430 \u0441\u0447\u0451\u0442 \u0442\u043e\u0433\u043e, \u043d\u0430\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u043d\u0430\u0434\u0451\u0436\u0435\u043d \u0445\u043e\u0440\u043e\u0448\u0438\u0439 \u0432\u0430\u0440\u0438\u0430\u043d\u0442 (\u043d\u0430\u043f\u0440\u0438\u043c\u0435\u0440, 80/20 \u043f\u0440\u043e\u0442\u0438\u0432 \u0431\u043e\u043b\u0435\u0435 \u0448\u0443\u043c\u043d\u043e\u0433\u043e 70/30), \u043a\u0430\u043a \u0447\u0430\u0441\u0442\u043e \u043f\u0440\u043e\u0438\u0441\u0445\u043e\u0434\u0438\u0442 \u0441\u043c\u0435\u043d\u0430 \u043f\u0440\u0430\u0432\u0438\u043b\u0430, \u0441\u043b\u0435\u0434\u0438\u0442\u0435 \u043b\u0438 \u0432\u044b \u0437\u0430 \u0434\u0432\u0443\u043c\u044f \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u0430\u043c\u0438 \u0438\u043b\u0438 \u0437\u0430 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u0438\u043c\u0438 \u0438 \u043f\u0440\u0438\u0445\u043e\u0434\u0438\u0442 \u043b\u0438 \u043e\u0431\u0440\u0430\u0442\u043d\u0430\u044f \u0441\u0432\u044f\u0437\u044c \u0432 \u0432\u0438\u0434\u0435 \u043d\u0430\u0433\u0440\u0430\u0434, \u043f\u043e\u0442\u0435\u0440\u044c \u0438\u043b\u0438 \u0442\u043e\u0433\u043e \u0438 \u0434\u0440\u0443\u0433\u043e\u0433\u043e. \u0414\u0435\u0442\u0435\u0440\u043c\u0438\u043d\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u044b\u0435 \u0432\u0435\u0440\u0441\u0438\u0438 \u0443\u0431\u0438\u0440\u0430\u044e\u0442 \u0441\u043b\u0443\u0447\u0430\u0439\u043d\u043e\u0441\u0442\u044c \u0432\u043e\u0432\u0441\u0435 \u0438 \u043f\u0440\u043e\u0441\u0442\u043e \u043f\u0435\u0440\u0435\u0432\u043e\u0440\u0430\u0447\u0438\u0432\u0430\u044e\u0442 \u043f\u0440\u0430\u0432\u0438\u043b\u043e, \u043a\u043e\u0442\u043e\u0440\u043e\u0435 \u0432\u0441\u0435\u0433\u0434\u0430 \u0432\u044b\u043f\u043e\u043b\u043d\u044f\u0435\u0442\u0441\u044f."},en:{about:"PRL is a probabilistic reversal-learning task. You face two options and pick one on each trial; the better option pays off most of the time but not always, so you learn by trial and error which one is currently 'good'. Without warning the rule flips and the other option becomes better, and your job is to notice the change and switch, instead of stubbornly sticking with what used to work.",benefit:"It trains cognitive flexibility and feedback-driven learning under uncertainty: holding onto a rule while it pays, distinguishing a genuine reversal from a run of bad luck, and updating your choice without over-reacting to a single misleading outcome.",history:"The idea grew out of mid-20th-century animal learning research, where animals were taught a simple discrimination and then had the reward contingencies reversed to see how fast they could relearn. The probabilistic version for humans took shape in cognitive neuroscience around the early 2000s, when noisy feedback was added to better mimic real-world uncertainty and to probe how the brain copes with changing rules.",creator:"There is no single inventor. Reversal learning comes from the behaviourist tradition of discrimination-reversal studies in the 1940s and 1950s, associated with researchers such as Harry Harlow, the Kendlers and N. J. Mackintosh. The modern probabilistic reversal task used in human imaging is commonly credited to Roshan Cools, Luke Clark and colleagues at Cambridge around 2002, building on that older lineage rather than founding it.",methods:"Treat one bad outcome as noise, not proof: only conclude the rule has flipped after several misses in a row from the option you thought was best. Keep a rough mental tally of recent results rather than reacting to the very last trial, and once you have switched, commit to the new choice long enough to confirm it before doubting it again.",duration:"Short, regular sessions work best: roughly 5 to 10 minutes, a few times a week. The skill being exercised is fast updating, so several short blocks beat one long grind, where fatigue makes you either too twitchy or too rigid.",research:"Evidence is strongest for the obvious thing: with practice you get better at the task itself and at telling real rule changes apart from unlucky streaks, and the task reliably tracks differences in flexibility between groups in clinical and neuroscience research. Claims that this kind of training broadly transfers to everyday decision-making or general 'cognitive flexibility' are weak and contested, and the wider brain-training literature gives little reason to expect far transfer, so treat any grand promise with caution.",rec:"Before you switch, ask yourself whether you have really seen a pattern of failures or just one unlucky result, and only flip when the evidence has piled up.",faq:[["Why did I lose even though I picked the 'right' option?","Because the good option only pays off most of the time, not every time. A single loss is often just noise; the rule has not necessarily reversed."],["How do I know when the rule has actually flipped?","Look for a run of poor outcomes from the choice that used to work, not one bad result. Once misses cluster together, that is your cue to switch."],["Will this make me more flexible in real life?","It will reliably make you better at this task and similar ones. Broad transfer to everyday decisions is not well supported, so enjoy the practice without banking on life-changing gains."]],variants:"Variations change the difficulty by adjusting how reliable the good option is (for example 80/20 versus a noisier 70/30), how often reversals happen, whether you track two options or several, and whether feedback comes as rewards, as losses, or both. Deterministic versions remove the luck entirely and simply flip a rule that always holds."},es:{about:"PRL es una tarea de aprendizaje por reversi\xf3n probabil\xedstico. Tienes dos opciones y eliges una en cada intento; la mejor opci\xf3n acierta la mayor\xeda de las veces, pero no siempre, as\xed que aprendes por ensayo y error cu\xe1l es la 'buena' en cada momento. Sin previo aviso, la regla se invierte y la otra opci\xf3n pasa a ser la mejor; tu tarea es darte cuenta del cambio y cambiar, en lugar de aferrarte tercamente a lo que antes funcionaba.",benefit:"Entrena la flexibilidad cognitiva y el aprendizaje guiado por la retroalimentaci\xf3n en condiciones de incertidumbre: mantener una regla mientras da frutos, distinguir una reversi\xf3n genuina de una racha de mala suerte y actualizar tu elecci\xf3n sin sobrerreaccionar a un \xfanico resultado enga\xf1oso.",history:"La idea surgi\xf3 de la investigaci\xf3n sobre aprendizaje animal de mediados del siglo XX, donde se ense\xf1aba a los animales una discriminaci\xf3n sencilla y luego se invert\xedan las contingencias de recompensa para ver con qu\xe9 rapidez pod\xedan reaprender. La versi\xf3n probabil\xedstica para humanos tom\xf3 forma en la neurociencia cognitiva a comienzos de los a\xf1os 2000, cuando se a\xf1adi\xf3 retroalimentaci\xf3n ruidosa para imitar mejor la incertidumbre del mundo real y sondear c\xf3mo afronta el cerebro las reglas cambiantes.",creator:"No hay un \xfanico inventor. El aprendizaje por reversi\xf3n proviene de la tradici\xf3n conductista de los estudios de reversi\xf3n de discriminaciones de los a\xf1os 40 y 50, asociada a investigadores como Harry Harlow, los Kendler y N. J. Mackintosh. La versi\xf3n probabil\xedstica moderna usada en neuroimagen humana suele atribuirse a Roshan Cools, Luke Clark y sus colaboradores en Cambridge hacia 2002, que se apoyaron en ese linaje m\xe1s antiguo en lugar de fundarlo.",methods:"Trata un mal resultado como ruido, no como prueba: solo concluye que la regla se ha invertido tras varios fallos seguidos de la opci\xf3n que cre\xedas mejor. Lleva un recuento mental aproximado de los resultados recientes en lugar de reaccionar al \xfaltimo intento, y una vez que hayas cambiado, comprom\xe9tete con la nueva elecci\xf3n el tiempo suficiente para confirmarla antes de volver a dudar.",duration:"Funcionan mejor las sesiones cortas y regulares: en torno a 5 o 10 minutos, unas pocas veces por semana. La habilidad que se ejercita es la actualizaci\xf3n r\xe1pida, as\xed que varios bloques cortos superan a una sola sesi\xf3n larga, donde el cansancio te vuelve demasiado nervioso o demasiado r\xedgido.",research:"La evidencia es m\xe1s fuerte para lo obvio: con la pr\xe1ctica mejoras en la propia tarea y en distinguir cambios reales de regla de las rachas de mala suerte, y la tarea refleja de forma fiable las diferencias de flexibilidad entre grupos en la investigaci\xf3n cl\xednica y neurocient\xedfica. Las afirmaciones de que este tipo de entrenamiento se transfiere ampliamente a la toma de decisiones cotidiana o a una 'flexibilidad cognitiva' general son d\xe9biles y discutidas, y la literatura m\xe1s amplia sobre entrenamiento mental da pocas razones para esperar transferencia lejana, as\xed que toma con cautela cualquier gran promesa.",rec:"Antes de cambiar, preg\xfantate si realmente has visto un patr\xf3n de fallos o solo un resultado desafortunado, y cambia \xfanicamente cuando la evidencia se haya acumulado.",faq:[["\xbfPor qu\xe9 perd\xed aunque eleg\xed la opci\xf3n 'correcta'?","Porque la opci\xf3n buena solo acierta la mayor\xeda de las veces, no siempre. Una sola p\xe9rdida suele ser puro ruido; la regla no se ha invertido necesariamente."],["\xbfC\xf3mo s\xe9 cu\xe1ndo se ha invertido de verdad la regla?","Busca una serie de malos resultados de la opci\xf3n que antes funcionaba, no un \xfanico mal resultado. Cuando los fallos se agrupan, esa es tu se\xf1al para cambiar."],["\xbfEsto me har\xe1 m\xe1s flexible en la vida real?","Te har\xe1 mejorar de forma fiable en esta tarea y en otras parecidas. La transferencia amplia a las decisiones cotidianas no est\xe1 bien respaldada, as\xed que disfruta de la pr\xe1ctica sin contar con cambios que te transformen la vida."]],variants:"Las variantes cambian la dificultad ajustando cu\xe1n fiable es la opci\xf3n buena (por ejemplo 80/20 frente a un 70/30 m\xe1s ruidoso), con qu\xe9 frecuencia ocurren las reversiones, si sigues dos opciones o varias, y si la retroalimentaci\xf3n llega como recompensas, como p\xe9rdidas o ambas. Las versiones deterministas eliminan por completo el azar y simplemente invierten una regla que siempre se cumple."},de:{about:"PRL ist eine Aufgabe zum probabilistischen Umkehrlernen. Du stehst vor zwei Optionen und w\xe4hlst bei jedem Durchgang eine aus; die bessere Option zahlt sich meistens aus, aber nicht immer, und so lernst du durch Versuch und Irrtum, welche gerade die 'gute' ist. Ohne Vorwarnung kippt die Regel und die andere Option wird besser. Deine Aufgabe ist es, die Ver\xe4nderung zu bemerken und zu wechseln, statt stur an dem festzuhalten, was fr\xfcher funktioniert hat.",benefit:"Sie schult kognitive Flexibilit\xe4t und r\xfcckmeldungsgesteuertes Lernen unter Unsicherheit: an einer Regel festzuhalten, solange sie sich auszahlt, eine echte Umkehrung von einer Pechstr\xe4hne zu unterscheiden und die eigene Wahl anzupassen, ohne auf ein einzelnes irref\xfchrendes Ergebnis \xfcberzureagieren.",history:"Die Idee entwuchs der Tierlernforschung der Mitte des 20. Jahrhunderts, in der Tieren eine einfache Unterscheidung beigebracht und dann die Belohnungsbedingungen umgekehrt wurden, um zu sehen, wie schnell sie umlernen konnten. Die probabilistische Version f\xfcr Menschen nahm in der kognitiven Neurowissenschaft um die fr\xfchen 2000er Jahre Gestalt an, als verrauschte R\xfcckmeldung hinzugef\xfcgt wurde, um die Unsicherheit der realen Welt besser nachzubilden und zu untersuchen, wie das Gehirn mit wechselnden Regeln umgeht.",creator:"Es gibt keinen einzelnen Erfinder. Das Umkehrlernen entstammt der behavioristischen Tradition der Diskriminations-Umkehr-Studien der 1940er und 1950er Jahre, verbunden mit Forschern wie Harry Harlow, den Kendlers und N. J. Mackintosh. Die moderne probabilistische Umkehraufgabe, wie sie in der bildgebenden Forschung am Menschen verwendet wird, wird gemeinhin Roshan Cools, Luke Clark und Kollegen in Cambridge um 2002 zugeschrieben, die auf dieser \xe4lteren Linie aufbauten, anstatt sie zu begr\xfcnden.",methods:"Behandle ein einzelnes schlechtes Ergebnis als Rauschen, nicht als Beweis: Schlie\xdfe erst nach mehreren Fehlschl\xe4gen in Folge bei der Option, die du f\xfcr die beste hieltst, dass die Regel gekippt ist. F\xfchre eine grobe gedankliche Bilanz der j\xfcngsten Ergebnisse, statt auf den allerletzten Durchgang zu reagieren, und halte nach einem Wechsel lange genug an der neuen Wahl fest, um sie zu best\xe4tigen, bevor du wieder an ihr zweifelst.",duration:"Kurze, regelm\xe4\xdfige Sitzungen funktionieren am besten: ungef\xe4hr 5 bis 10 Minuten, ein paar Mal pro Woche. Die ge\xfcbte F\xe4higkeit ist schnelles Aktualisieren, daher schlagen mehrere kurze Bl\xf6cke ein langes Durchackern, bei dem Erm\xfcdung dich entweder zu zappelig oder zu starr macht.",research:"Am st\xe4rksten ist die Evidenz f\xfcr das Naheliegende: Mit \xdcbung wirst du in der Aufgabe selbst besser und darin, echte Regel\xe4nderungen von Pechstr\xe4hnen zu unterscheiden, und die Aufgabe bildet Unterschiede in der Flexibilit\xe4t zwischen Gruppen in der klinischen und neurowissenschaftlichen Forschung zuverl\xe4ssig ab. Behauptungen, dass diese Art von Training breit auf allt\xe4gliche Entscheidungen oder allgemeine 'kognitive Flexibilit\xe4t' \xfcbertrage, sind schwach und umstritten, und die breitere Gehirntraining-Literatur gibt wenig Anlass, einen Ferntransfer zu erwarten \u2014 begegne also jedem gro\xdfen Versprechen mit Vorsicht.",rec:"Bevor du wechselst, frage dich, ob du wirklich ein Muster von Fehlschl\xe4gen gesehen hast oder nur ein einziges Pechergebnis, und kippe erst, wenn sich die Belege geh\xe4uft haben.",faq:[["Warum habe ich verloren, obwohl ich die 'richtige' Option gew\xe4hlt habe?","Weil die gute Option sich nur meistens auszahlt, nicht jedes Mal. Ein einzelner Verlust ist oft blo\xdf Rauschen; die Regel hat sich nicht zwangsl\xe4ufig umgekehrt."],["Woran erkenne ich, dass die Regel tats\xe4chlich gekippt ist?","Achte auf eine Reihe schlechter Ergebnisse bei der Wahl, die fr\xfcher funktioniert hat, nicht auf ein einzelnes schlechtes Ergebnis. Sobald sich die Fehlschl\xe4ge h\xe4ufen, ist das dein Signal zum Wechseln."],["Macht mich das im echten Leben flexibler?","Es macht dich zuverl\xe4ssig besser in dieser Aufgabe und in \xe4hnlichen. Ein breiter \xdcbertrag auf allt\xe4gliche Entscheidungen ist nicht gut belegt, also genie\xdfe die \xdcbung, ohne auf lebensver\xe4ndernde Gewinne zu setzen."]],variants:"Abwandlungen ver\xe4ndern den Schwierigkeitsgrad, indem sie anpassen, wie zuverl\xe4ssig die gute Option ist (etwa 80/20 gegen\xfcber einem verrauschteren 70/30), wie oft Umkehrungen vorkommen, ob du zwei oder mehrere Optionen verfolgst und ob die R\xfcckmeldung als Belohnung, als Verlust oder als beides kommt. Deterministische Versionen entfernen den Zufall vollst\xe4ndig und kippen einfach eine Regel, die immer gilt."},pt:{about:"PRL \xe9 uma tarefa de aprendizagem por revers\xe3o probabil\xedstica. Voc\xea se depara com duas op\xe7\xf5es e escolhe uma a cada tentativa; a melhor op\xe7\xe3o compensa na maioria das vezes, mas n\xe3o sempre, ent\xe3o voc\xea aprende por tentativa e erro qual delas \xe9 a 'boa' no momento. Sem aviso, a regra se inverte e a outra op\xe7\xe3o passa a ser a melhor, e sua miss\xe3o \xe9 perceber a mudan\xe7a e trocar, em vez de insistir teimosamente no que costumava funcionar.",benefit:"Treina a flexibilidade cognitiva e a aprendizagem orientada por feedback sob incerteza: manter uma regra enquanto ela compensa, distinguir uma revers\xe3o genu\xedna de uma sequ\xeancia de azar e atualizar sua escolha sem reagir em excesso a um \xfanico resultado enganoso.",history:"A ideia nasceu da pesquisa sobre aprendizagem animal de meados do s\xe9culo XX, em que animais eram ensinados a fazer uma discrimina\xe7\xe3o simples e depois tinham as conting\xeancias de recompensa invertidas, para ver qu\xe3o r\xe1pido conseguiam reaprender. A vers\xe3o probabil\xedstica para humanos tomou forma na neuroci\xeancia cognitiva por volta do in\xedcio dos anos 2000, quando se acrescentou feedback ruidoso para imitar melhor a incerteza do mundo real e investigar como o c\xe9rebro lida com regras em mudan\xe7a.",creator:"N\xe3o h\xe1 um \xfanico inventor. A aprendizagem por revers\xe3o vem da tradi\xe7\xe3o behaviorista dos estudos de revers\xe3o de discrimina\xe7\xe3o das d\xe9cadas de 1940 e 1950, associada a pesquisadores como Harry Harlow, os Kendler e N. J. Mackintosh. A moderna tarefa de revers\xe3o probabil\xedstica usada em neuroimagem humana costuma ser creditada a Roshan Cools, Luke Clark e colegas em Cambridge por volta de 2002, que se apoiaram nessa linhagem mais antiga em vez de fund\xe1-la.",methods:"Trate um resultado ruim como ru\xeddo, n\xe3o como prova: s\xf3 conclua que a regra se inverteu depois de v\xe1rios erros seguidos da op\xe7\xe3o que voc\xea julgava ser a melhor. Mantenha uma contagem mental aproximada dos resultados recentes em vez de reagir \xe0 \xfaltima tentativa, e, uma vez que tenha trocado, comprometa-se com a nova escolha por tempo suficiente para confirm\xe1-la antes de voltar a duvidar.",duration:"Sess\xf5es curtas e regulares funcionam melhor: cerca de 5 a 10 minutos, algumas vezes por semana. A habilidade exercitada \xe9 a atualiza\xe7\xe3o r\xe1pida, ent\xe3o v\xe1rios blocos curtos batem uma maratona longa, em que o cansa\xe7o deixa voc\xea nervoso demais ou r\xedgido demais.",research:"A evid\xeancia \xe9 mais forte para o \xf3bvio: com a pr\xe1tica voc\xea melhora na pr\xf3pria tarefa e em distinguir mudan\xe7as reais de regra de sequ\xeancias de azar, e a tarefa acompanha de forma confi\xe1vel diferen\xe7as de flexibilidade entre grupos na pesquisa cl\xednica e em neuroci\xeancia. Afirma\xe7\xf5es de que esse tipo de treino se transfere amplamente para a tomada de decis\xe3o cotidiana ou para a 'flexibilidade cognitiva' geral s\xe3o fracas e contestadas, e a literatura mais ampla sobre treino cerebral d\xe1 poucos motivos para esperar transfer\xeancia distante, ent\xe3o trate qualquer promessa grandiosa com cautela.",rec:"Antes de trocar, pergunte-se se realmente viu um padr\xe3o de falhas ou apenas um resultado de azar, e s\xf3 inverta quando as evid\xeancias tiverem se acumulado.",faq:[["Por que perdi mesmo escolhendo a op\xe7\xe3o 'certa'?","Porque a op\xe7\xe3o boa s\xf3 compensa na maioria das vezes, n\xe3o em todas. Uma \xfanica perda costuma ser apenas ru\xeddo; a regra n\xe3o necessariamente se inverteu."],["Como sei quando a regra de fato mudou?","Procure por uma sequ\xeancia de resultados ruins da escolha que costumava funcionar, n\xe3o por um \xfanico resultado ruim. Quando os erros se agrupam, esse \xe9 o seu sinal para trocar."],["Isto vai me tornar mais flex\xedvel na vida real?","Vai confiavelmente deix\xe1-lo melhor nesta tarefa e em outras parecidas. A transfer\xeancia ampla para decis\xf5es cotidianas n\xe3o tem bom respaldo, ent\xe3o aproveite a pr\xe1tica sem apostar em ganhos que mudam a vida."]],variants:"As varia\xe7\xf5es mudam a dificuldade ajustando o qu\xe3o confi\xe1vel \xe9 a op\xe7\xe3o boa (por exemplo 80/20 contra um mais ruidoso 70/30), com que frequ\xeancia ocorrem as revers\xf5es, se voc\xea acompanha duas op\xe7\xf5es ou v\xe1rias, e se o feedback vem como recompensas, como perdas ou ambos. Vers\xf5es determin\xedsticas removem a sorte por completo e simplesmente invertem uma regra que sempre vale."},hi:{about:"PRL \u090f\u0915 \u092a\u094d\u0930\u093e\u092f\u093f\u0915\u0924\u093e-\u0906\u0927\u093e\u0930\u093f\u0924 \u0909\u0932\u091f-\u0938\u0940\u0916\u0928\u0947 (\u092a\u094d\u0930\u094b\u092c\u0948\u092c\u093f\u0932\u093f\u0938\u094d\u091f\u093f\u0915 \u0930\u093f\u0935\u0930\u094d\u0938\u0932-\u0932\u0930\u094d\u0928\u093f\u0902\u0917) \u0935\u093e\u0932\u093e \u0915\u093e\u0930\u094d\u092f \u0939\u0948\u0964 \u0906\u092a\u0915\u0947 \u0938\u093e\u092e\u0928\u0947 \u0926\u094b \u0935\u093f\u0915\u0932\u094d\u092a \u0939\u094b\u0924\u0947 \u0939\u0948\u0902 \u0914\u0930 \u0939\u0930 \u092c\u093e\u0930\u0940 \u092a\u0930 \u0906\u092a \u090f\u0915 \u091a\u0941\u0928\u0924\u0947 \u0939\u0948\u0902; \u092c\u0947\u0939\u0924\u0930 \u0935\u093f\u0915\u0932\u094d\u092a \u091c\u093c\u094d\u092f\u093e\u0926\u093e\u0924\u0930 \u092c\u093e\u0930 \u0907\u0928\u093e\u092e \u0926\u0947\u0924\u093e \u0939\u0948 \u092a\u0930 \u0939\u092e\u0947\u0936\u093e \u0928\u0939\u0940\u0902, \u0907\u0938\u0932\u093f\u090f \u0906\u092a \u0906\u091c\u093c\u092e\u093e\u0907\u0936-\u0914\u0930-\u0917\u0932\u0924\u0940 \u0938\u0947 \u0938\u0940\u0916\u0924\u0947 \u0939\u0948\u0902 \u0915\u093f \u092b\u093c\u093f\u0932\u0939\u093e\u0932 \u0915\u094c\u0928-\u0938\u093e '\u0905\u091a\u094d\u091b\u093e' \u0939\u0948\u0964 \u092c\u093f\u0928\u093e \u0915\u093f\u0938\u0940 \u091a\u0947\u0924\u093e\u0935\u0928\u0940 \u0915\u0947 \u0928\u093f\u092f\u092e \u092a\u0932\u091f \u091c\u093e\u0924\u093e \u0939\u0948 \u0914\u0930 \u0926\u0942\u0938\u0930\u093e \u0935\u093f\u0915\u0932\u094d\u092a \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u0924\u093e \u0939\u0948, \u0914\u0930 \u0906\u092a\u0915\u093e \u0915\u093e\u092e \u0939\u0948 \u0907\u0938 \u092c\u0926\u0932\u093e\u0935 \u0915\u094b \u092d\u093e\u0901\u092a\u0915\u0930 \u092a\u093e\u0932\u093e \u092c\u0926\u0932\u0928\u093e \u2014 \u0928 \u0915\u093f \u091c\u093c\u093f\u0926 \u092e\u0947\u0902 \u0909\u0938\u0940 \u0938\u0947 \u091a\u093f\u092a\u0915\u0947 \u0930\u0939\u0928\u093e \u091c\u094b \u092a\u0939\u0932\u0947 \u0915\u093e\u092e \u0915\u0930 \u0930\u0939\u093e \u0925\u093e\u0964",benefit:"\u092f\u0939 \u0938\u0902\u091c\u094d\u091e\u093e\u0928\u093e\u0924\u094d\u092e\u0915 \u0932\u091a\u0940\u0932\u093e\u092a\u0928 \u0914\u0930 \u0905\u0928\u093f\u0936\u094d\u091a\u093f\u0924\u0924\u093e \u0915\u0947 \u092c\u0940\u091a \u092b\u093c\u0940\u0921\u092c\u0948\u0915 \u0938\u0947 \u091a\u0932\u0928\u0947 \u0935\u093e\u0932\u0940 \u0938\u0940\u0916 \u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0930\u093e\u0924\u093e \u0939\u0948: \u091c\u092c \u0924\u0915 \u0915\u094b\u0908 \u0928\u093f\u092f\u092e \u092b\u093c\u093e\u092f\u0926\u093e \u0926\u0947 \u0930\u0939\u093e \u0939\u094b \u0924\u092c \u0924\u0915 \u0909\u0938\u0947 \u0925\u093e\u092e\u0947 \u0930\u0916\u0928\u093e, \u0905\u0938\u0932\u0940 \u0909\u0932\u091f\u092b\u0947\u0930 \u0915\u094b \u092c\u0941\u0930\u0947 \u092d\u093e\u0917\u094d\u092f \u0915\u0940 \u0932\u0921\u093c\u0940 \u0938\u0947 \u0905\u0932\u0917 \u092a\u0939\u091a\u093e\u0928\u0928\u093e, \u0914\u0930 \u0915\u093f\u0938\u0940 \u090f\u0915 \u092d\u094d\u0930\u093e\u092e\u0915 \u0928\u0924\u0940\u091c\u0947 \u092a\u0930 \u0939\u0926 \u0938\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0915\u093f\u090f \u092c\u093f\u0928\u093e \u0905\u092a\u0928\u093e \u091a\u0941\u0928\u093e\u0935 \u0905\u092a\u0921\u0947\u091f \u0915\u0930\u0928\u093e\u0964",history:"\u092f\u0939 \u0935\u093f\u091a\u093e\u0930 \u092c\u0940\u0938\u0935\u0940\u0902 \u0938\u0926\u0940 \u0915\u0947 \u092e\u0927\u094d\u092f \u0915\u0947 \u092a\u0936\u0941-\u0938\u0940\u0916 \u0938\u0902\u092c\u0902\u0927\u0940 \u0936\u094b\u0927 \u0938\u0947 \u092a\u0928\u092a\u093e, \u091c\u0939\u093e\u0901 \u091c\u093e\u0928\u0935\u0930\u094b\u0902 \u0915\u094b \u090f\u0915 \u0938\u0930\u0932 \u092d\u0947\u0926 \u0938\u093f\u0916\u093e\u092f\u093e \u091c\u093e\u0924\u093e \u0914\u0930 \u092b\u093f\u0930 \u0907\u0928\u093e\u092e \u0915\u0940 \u0936\u0930\u094d\u0924\u0947\u0902 \u0909\u0932\u091f \u0926\u0940 \u091c\u093e\u0924\u0940\u0902 \u0924\u093e\u0915\u093f \u0926\u0947\u0916\u093e \u091c\u093e \u0938\u0915\u0947 \u0915\u093f \u0935\u0947 \u0915\u093f\u0924\u0928\u0940 \u091c\u0932\u094d\u0926\u0940 \u0926\u094b\u092c\u093e\u0930\u093e \u0938\u0940\u0916 \u092a\u093e\u0924\u0947 \u0939\u0948\u0902\u0964 \u0907\u0902\u0938\u093e\u0928\u094b\u0902 \u0915\u0947 \u0932\u093f\u090f \u0907\u0938\u0915\u093e \u092a\u094d\u0930\u093e\u092f\u093f\u0915\u0924\u093e-\u0906\u0927\u093e\u0930\u093f\u0924 \u0930\u0942\u092a 2000 \u0915\u0947 \u0926\u0936\u0915 \u0915\u0940 \u0936\u0941\u0930\u0941\u0906\u0924 \u0915\u0947 \u0906\u0938\u092a\u093e\u0938 \u0938\u0902\u091c\u094d\u091e\u093e\u0928\u093e\u0924\u094d\u092e\u0915 \u0924\u0902\u0924\u094d\u0930\u093f\u0915\u093e-\u0935\u093f\u091c\u094d\u091e\u093e\u0928 \u092e\u0947\u0902 \u0906\u0915\u093e\u0930 \u0932\u0947\u0928\u0947 \u0932\u0917\u093e, \u091c\u092c \u0905\u0938\u0932 \u0926\u0941\u0928\u093f\u092f\u093e \u0915\u0940 \u0905\u0928\u093f\u0936\u094d\u091a\u093f\u0924\u0924\u093e \u0915\u0940 \u092c\u0947\u0939\u0924\u0930 \u0928\u0915\u0932 \u0915\u0930\u0928\u0947 \u0914\u0930 \u092f\u0939 \u091c\u093e\u0901\u091a\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0915\u093f \u0926\u093f\u092e\u093e\u0917 \u092c\u0926\u0932\u0924\u0947 \u0928\u093f\u092f\u092e\u094b\u0902 \u0938\u0947 \u0915\u0948\u0938\u0947 \u0928\u093f\u092a\u091f\u0924\u093e \u0939\u0948, \u092b\u093c\u0940\u0921\u092c\u0948\u0915 \u092e\u0947\u0902 \u0936\u094b\u0930 (\u0928\u0949\u0907\u091c\u093c) \u091c\u094b\u0921\u093c\u093e \u0917\u092f\u093e\u0964",creator:"\u0907\u0938\u0915\u093e \u0915\u094b\u0908 \u090f\u0915\u092e\u093e\u0924\u094d\u0930 \u0906\u0935\u093f\u0937\u094d\u0915\u093e\u0930\u0915 \u0928\u0939\u0940\u0902 \u0939\u0948\u0964 \u0909\u0932\u091f-\u0938\u0940\u0916\u0928\u093e 1940 \u0914\u0930 1950 \u0915\u0947 \u0926\u0936\u0915 \u0915\u0947 \u092d\u0947\u0926-\u0909\u0932\u091f\u092b\u0947\u0930 (\u0921\u093f\u0938\u094d\u0915\u094d\u0930\u093f\u092e\u093f\u0928\u0947\u0936\u0928-\u0930\u093f\u0935\u0930\u094d\u0938\u0932) \u0905\u0927\u094d\u092f\u092f\u0928\u094b\u0902 \u0915\u0940 \u0935\u094d\u092f\u0935\u0939\u093e\u0930\u0935\u093e\u0926\u0940 \u092a\u0930\u0902\u092a\u0930\u093e \u0938\u0947 \u0906\u0924\u093e \u0939\u0948, \u091c\u094b Harry Harlow, Kendler \u0926\u0902\u092a\u0924\u0940 \u0914\u0930 N. J. Mackintosh \u091c\u0948\u0938\u0947 \u0936\u094b\u0927\u0915\u0930\u094d\u0924\u093e\u0913\u0902 \u0938\u0947 \u091c\u0941\u0921\u093c\u093e \u0939\u0948\u0964 \u0907\u0902\u0938\u093e\u0928\u0940 \u0907\u092e\u0947\u091c\u093f\u0902\u0917 \u092e\u0947\u0902 \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0939\u094b\u0928\u0947 \u0935\u093e\u0932\u093e \u0906\u0927\u0941\u0928\u093f\u0915 \u092a\u094d\u0930\u093e\u092f\u093f\u0915\u0924\u093e-\u0906\u0927\u093e\u0930\u093f\u0924 \u0909\u0932\u091f-\u0915\u093e\u0930\u094d\u092f \u0906\u092e\u0924\u094c\u0930 \u092a\u0930 Roshan Cools, Luke Clark \u0914\u0930 \u0915\u0948\u0902\u092c\u094d\u0930\u093f\u091c \u0915\u0947 \u0909\u0928\u0915\u0947 \u0938\u093e\u0925\u093f\u092f\u094b\u0902 \u0915\u094b (\u0932\u0917\u092d\u0917 2002 \u092e\u0947\u0902) \u0936\u094d\u0930\u0947\u092f \u0926\u093f\u092f\u093e \u091c\u093e\u0924\u093e \u0939\u0948, \u091c\u093f\u0928\u094d\u0939\u094b\u0902\u0928\u0947 \u0907\u0938 \u092a\u0941\u0930\u093e\u0928\u0940 \u092a\u0930\u0902\u092a\u0930\u093e \u092a\u0930 \u0906\u0917\u0947 \u092c\u0922\u093c\u0924\u0947 \u0939\u0941\u090f \u0907\u0938\u0947 \u0917\u0922\u093c\u093e, \u0928 \u0915\u093f \u0907\u0938\u0915\u0940 \u0928\u0940\u0902\u0935 \u0930\u0916\u0940\u0964",methods:"\u090f\u0915 \u092c\u0941\u0930\u0947 \u0928\u0924\u0940\u091c\u0947 \u0915\u094b \u0936\u094b\u0930 \u092e\u093e\u0928\u093f\u090f, \u0938\u092c\u0942\u0924 \u0928\u0939\u0940\u0902: \u092f\u0939 \u0928\u0924\u0940\u091c\u093e \u0924\u092d\u0940 \u0928\u093f\u0915\u093e\u0932\u093f\u090f \u0915\u093f \u0928\u093f\u092f\u092e \u092a\u0932\u091f \u0917\u092f\u093e \u0939\u0948 \u091c\u092c \u0909\u0938\u0940 \u0935\u093f\u0915\u0932\u094d\u092a \u0938\u0947, \u091c\u093f\u0938\u0947 \u0906\u092a \u0938\u092c\u0938\u0947 \u0905\u091a\u094d\u091b\u093e \u0938\u092e\u091d\u0924\u0947 \u0925\u0947, \u0932\u0917\u093e\u0924\u093e\u0930 \u0915\u0908 \u092c\u093e\u0930 \u091a\u0942\u0915 \u0939\u094b \u091c\u093e\u090f\u0964 \u092c\u093f\u0932\u094d\u0915\u0941\u0932 \u0906\u0916\u093c\u093f\u0930\u0940 \u092c\u093e\u0930\u0940 \u092a\u0930 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0915\u0930\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u0939\u093e\u0932 \u0915\u0947 \u0928\u0924\u0940\u091c\u094b\u0902 \u0915\u093e \u090f\u0915 \u092e\u094b\u091f\u093e \u092e\u093e\u0928\u0938\u093f\u0915 \u0939\u093f\u0938\u093e\u092c \u0930\u0916\u093f\u090f, \u0914\u0930 \u090f\u0915 \u092c\u093e\u0930 \u092a\u093e\u0932\u093e \u092c\u0926\u0932 \u0932\u0947\u0928\u0947 \u0915\u0947 \u092c\u093e\u0926 \u0928\u090f \u091a\u0941\u0928\u093e\u0935 \u092a\u0930 \u0907\u0924\u0928\u0940 \u0926\u0947\u0930 \u091f\u093f\u0915\u0947 \u0930\u0939\u093f\u090f \u0915\u093f \u0909\u0938\u0947 \u092a\u0941\u0937\u094d\u091f \u0915\u0930 \u0938\u0915\u0947\u0902, \u0909\u0938\u0938\u0947 \u092a\u0939\u0932\u0947 \u0926\u094b\u092c\u093e\u0930\u093e \u0936\u0915 \u092e\u0924 \u0915\u0940\u091c\u093f\u090f\u0964",duration:"\u091b\u094b\u091f\u0947, \u0928\u093f\u092f\u092e\u093f\u0924 \u0938\u0924\u094d\u0930 \u0938\u092c\u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u0915\u093e\u092e \u0915\u0930\u0924\u0947 \u0939\u0948\u0902: \u0915\u0930\u0940\u092c 5 \u0938\u0947 10 \u092e\u093f\u0928\u091f, \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u0915\u0941\u091b \u092c\u093e\u0930\u0964 \u091c\u093f\u0938 \u0915\u094c\u0936\u0932 \u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0939\u094b \u0930\u0939\u093e \u0939\u0948 \u0935\u0939 \u0924\u0947\u091c\u093c \u0905\u092a\u0921\u0947\u091f \u0915\u0930\u0928\u093e \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u090f\u0915 \u0932\u0902\u092c\u0940 \u092a\u093f\u0938\u093e\u0908 \u0915\u0947 \u092c\u091c\u093e\u092f \u0915\u0908 \u091b\u094b\u091f\u0947 \u0916\u0902\u0921 \u092c\u0947\u0939\u0924\u0930 \u0930\u0939\u0924\u0947 \u0939\u0948\u0902, \u091c\u0939\u093e\u0901 \u0925\u0915\u093e\u0928 \u0906\u092a\u0915\u094b \u092f\u093e \u0924\u094b \u0939\u0926 \u0938\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0939\u0921\u093c\u092c\u0921\u093c\u093e \u092f\u093e \u0939\u0926 \u0938\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0905\u0915\u0921\u093c\u0942 \u092c\u0928\u093e \u0926\u0947\u0924\u0940 \u0939\u0948\u0964",research:"\u0938\u092c\u0938\u0947 \u092a\u0941\u0916\u093c\u094d\u0924\u093e \u0938\u092c\u0942\u0924 \u0909\u0938\u0940 \u0938\u094d\u092a\u0937\u094d\u091f \u092c\u093e\u0924 \u0915\u093e \u0939\u0948: \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0947 \u0938\u093e\u0925 \u0906\u092a \u0907\u0938 \u0915\u093e\u0930\u094d\u092f \u092e\u0947\u0902 \u0914\u0930 \u0905\u0938\u0932\u0940 \u0928\u093f\u092f\u092e-\u092c\u0926\u0932\u093e\u0935\u094b\u0902 \u0915\u094b \u092c\u0926\u0915\u093f\u0938\u094d\u092e\u0924\u0940 \u0915\u0940 \u0932\u0921\u093c\u0940 \u0938\u0947 \u0905\u0932\u0917 \u092a\u0939\u091a\u093e\u0928\u0928\u0947 \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u092f\u0939 \u0915\u093e\u0930\u094d\u092f \u091a\u093f\u0915\u093f\u0924\u094d\u0938\u0915\u0940\u092f \u0935 \u0924\u0902\u0924\u094d\u0930\u093f\u0915\u093e-\u0935\u093f\u091c\u094d\u091e\u093e\u0928 \u0936\u094b\u0927 \u092e\u0947\u0902 \u0938\u092e\u0942\u0939\u094b\u0902 \u0915\u0947 \u092c\u0940\u091a \u0932\u091a\u0940\u0932\u0947\u092a\u0928 \u0915\u0947 \u092b\u093c\u0930\u094d\u0915 \u0915\u094b \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0922\u0902\u0917 \u0938\u0947 \u0928\u093e\u092a\u0924\u093e \u0939\u0948\u0964 \u092f\u0939 \u0926\u093e\u0935\u093e \u0915\u093f \u0907\u0938 \u0924\u0930\u0939 \u0915\u093e \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0947 \u0928\u093f\u0930\u094d\u0923\u092f-\u0932\u0947\u0928\u0947 \u092f\u093e \u0906\u092e '\u0938\u0902\u091c\u094d\u091e\u093e\u0928\u093e\u0924\u094d\u092e\u0915 \u0932\u091a\u0940\u0932\u0947\u092a\u0928' \u0924\u0915 \u0935\u094d\u092f\u093e\u092a\u0915 \u0930\u0942\u092a \u0938\u0947 \u0939\u0938\u094d\u0924\u093e\u0902\u0924\u0930\u093f\u0924 \u0939\u094b\u0924\u093e \u0939\u0948 \u2014 \u0915\u092e\u091c\u093c\u094b\u0930 \u0914\u0930 \u0935\u093f\u0935\u093e\u0926\u093f\u0924 \u0939\u0948, \u0914\u0930 \u0926\u093f\u092e\u093e\u0917\u0940 \u0915\u0938\u0930\u0924 \u0915\u0947 \u0935\u094d\u092f\u093e\u092a\u0915 \u0938\u093e\u0939\u093f\u0924\u094d\u092f \u0938\u0947 \u0926\u0942\u0930-\u0939\u0938\u094d\u0924\u093e\u0902\u0924\u0930\u0923 \u0915\u0940 \u0909\u092e\u094d\u092e\u0940\u0926 \u0915\u0930\u0928\u0947 \u0915\u093e \u0915\u094b\u0908 \u0916\u093e\u0938 \u0906\u0927\u093e\u0930 \u0928\u0939\u0940\u0902 \u092e\u093f\u0932\u0924\u093e, \u0907\u0938\u0932\u093f\u090f \u0915\u093f\u0938\u0940 \u092d\u0940 \u092c\u0921\u093c\u0947 \u0935\u093e\u0926\u0947 \u0915\u094b \u0938\u093e\u0935\u0927\u093e\u0928\u0940 \u0938\u0947 \u0932\u0940\u091c\u093f\u090f\u0964",rec:"\u092a\u093e\u0932\u093e \u092c\u0926\u0932\u0928\u0947 \u0938\u0947 \u092a\u0939\u0932\u0947 \u0916\u0941\u0926 \u0938\u0947 \u092a\u0942\u091b\u093f\u090f \u0915\u093f \u0915\u094d\u092f\u093e \u0906\u092a\u0928\u0947 \u0938\u091a\u092e\u0941\u091a \u0935\u093f\u092b\u0932\u0924\u093e\u0913\u0902 \u0915\u093e \u090f\u0915 \u092a\u0948\u091f\u0930\u094d\u0928 \u0926\u0947\u0916\u093e \u0939\u0948 \u092f\u093e \u092c\u0938 \u090f\u0915 \u092c\u0926\u0915\u093f\u0938\u094d\u092e\u0924 \u0928\u0924\u0940\u091c\u093e, \u0914\u0930 \u0924\u092d\u0940 \u092a\u0932\u091f\u093f\u090f \u091c\u092c \u0938\u092c\u0942\u0924 \u0922\u0947\u0930 \u0939\u094b \u091a\u0941\u0915\u0947 \u0939\u094b\u0902\u0964",faq:[["\u092e\u0948\u0902\u0928\u0947 '\u0938\u0939\u0940' \u0935\u093f\u0915\u0932\u094d\u092a \u091a\u0941\u0928\u093e \u092b\u093f\u0930 \u092d\u0940 \u0939\u093e\u0930 \u0915\u094d\u092f\u094b\u0902 \u0917\u092f\u093e?","\u0915\u094d\u092f\u094b\u0902\u0915\u093f \u0905\u091a\u094d\u091b\u093e \u0935\u093f\u0915\u0932\u094d\u092a \u0938\u093f\u0930\u094d\u092b\u093c \u091c\u093c\u094d\u092f\u093e\u0926\u093e\u0924\u0930 \u092c\u093e\u0930 \u0907\u0928\u093e\u092e \u0926\u0947\u0924\u093e \u0939\u0948, \u0939\u0930 \u092c\u093e\u0930 \u0928\u0939\u0940\u0902\u0964 \u090f\u0915 \u0905\u0915\u0947\u0932\u0940 \u0939\u093e\u0930 \u0905\u0915\u094d\u0938\u0930 \u092c\u0938 \u0936\u094b\u0930 \u0939\u094b\u0924\u0940 \u0939\u0948; \u091c\u093c\u0930\u0942\u0930\u0940 \u0928\u0939\u0940\u0902 \u0915\u093f \u0928\u093f\u092f\u092e \u092a\u0932\u091f \u0917\u092f\u093e \u0939\u094b\u0964"],["\u092e\u0941\u091d\u0947 \u0915\u0948\u0938\u0947 \u092a\u0924\u093e \u091a\u0932\u0947 \u0915\u093f \u0928\u093f\u092f\u092e \u0938\u091a\u092e\u0941\u091a \u092a\u0932\u091f \u0917\u092f\u093e \u0939\u0948?","\u091c\u094b \u0935\u093f\u0915\u0932\u094d\u092a \u092a\u0939\u0932\u0947 \u0915\u093e\u092e \u0915\u0930 \u0930\u0939\u093e \u0925\u093e \u0909\u0938\u0938\u0947 \u090f\u0915 \u092c\u0941\u0930\u0947 \u0928\u0924\u0940\u091c\u0947 \u0915\u094b \u0928\u0939\u0940\u0902, \u092c\u0932\u094d\u0915\u093f \u092c\u0941\u0930\u0947 \u0928\u0924\u0940\u091c\u094b\u0902 \u0915\u0940 \u090f\u0915 \u0932\u0921\u093c\u0940 \u0915\u094b \u0926\u0947\u0916\u093f\u090f\u0964 \u091c\u092c \u091a\u0942\u0915\u0947\u0902 \u090f\u0915 \u0938\u093e\u0925 \u0917\u0941\u091a\u094d\u091b\u0947 \u092e\u0947\u0902 \u0906\u0928\u0947 \u0932\u0917\u0947\u0902, \u0935\u0939\u0940 \u0906\u092a\u0915\u0947 \u092a\u093e\u0932\u093e \u092c\u0926\u0932\u0928\u0947 \u0915\u093e \u0938\u0902\u0915\u0947\u0924 \u0939\u0948\u0964"],["\u0915\u094d\u092f\u093e \u092f\u0939 \u092e\u0941\u091d\u0947 \u0905\u0938\u0932 \u091c\u093c\u093f\u0902\u0926\u0917\u0940 \u092e\u0947\u0902 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0932\u091a\u0940\u0932\u093e \u092c\u0928\u093e \u0926\u0947\u0917\u093e?","\u092f\u0939 \u0906\u092a\u0915\u094b \u0907\u0938 \u0915\u093e\u0930\u094d\u092f \u0914\u0930 \u0907\u0938\u0938\u0947 \u092e\u093f\u0932\u0924\u0947-\u091c\u0941\u0932\u0924\u0947 \u0915\u093e\u0930\u094d\u092f\u094b\u0902 \u092e\u0947\u0902 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0922\u0902\u0917 \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u092c\u0928\u093e \u0926\u0947\u0917\u093e\u0964 \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0947 \u092b\u093c\u0948\u0938\u0932\u094b\u0902 \u0924\u0915 \u0935\u094d\u092f\u093e\u092a\u0915 \u0939\u0938\u094d\u0924\u093e\u0902\u0924\u0930\u0923 \u0915\u094b \u0905\u091a\u094d\u091b\u093e \u0938\u092e\u0930\u094d\u0925\u0928 \u0939\u093e\u0938\u093f\u0932 \u0928\u0939\u0940\u0902 \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u093e \u0906\u0928\u0902\u0926 \u0932\u0940\u091c\u093f\u090f \u092a\u0930 \u091c\u093c\u093f\u0902\u0926\u0917\u0940 \u092c\u0926\u0932 \u0926\u0947\u0928\u0947 \u0935\u093e\u0932\u0947 \u092b\u093c\u093e\u092f\u0926\u094b\u0902 \u092a\u0930 \u092e\u0924 \u091f\u0947\u0915\u093f\u090f\u0964"]],variants:"\u092c\u0926\u0932\u093e\u0935 \u0915\u0920\u093f\u0928\u093e\u0908 \u0915\u094b \u0907\u0938 \u0924\u0930\u0939 \u0918\u091f\u093e\u0924\u0947-\u092c\u0922\u093c\u093e\u0924\u0947 \u0939\u0948\u0902: \u0905\u091a\u094d\u091b\u093e \u0935\u093f\u0915\u0932\u094d\u092a \u0915\u093f\u0924\u0928\u093e \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0939\u0948 \u0907\u0938\u0947 \u0938\u092e\u093e\u092f\u094b\u091c\u093f\u0924 \u0915\u0930\u0915\u0947 (\u092e\u0938\u0932\u0928 80/20 \u092c\u0928\u093e\u092e \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0936\u094b\u0930 \u0935\u093e\u0932\u093e 70/30), \u0909\u0932\u091f\u092b\u0947\u0930 \u0915\u093f\u0924\u0928\u0940 \u092c\u093e\u0930 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902, \u0906\u092a \u0926\u094b \u0935\u093f\u0915\u0932\u094d\u092a\u094b\u0902 \u092a\u0930 \u0928\u091c\u093c\u0930 \u0930\u0916\u0924\u0947 \u0939\u0948\u0902 \u092f\u093e \u0915\u0908 \u092a\u0930, \u0914\u0930 \u092b\u093c\u0940\u0921\u092c\u0948\u0915 \u0907\u0928\u093e\u092e \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u0906\u0924\u093e \u0939\u0948, \u0928\u0941\u0915\u0938\u093e\u0928 \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902, \u092f\u093e \u0926\u094b\u0928\u094b\u0902 \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902\u0964 \u0928\u093f\u092f\u0924\u093e\u0924\u094d\u092e\u0915 (\u0921\u093f\u091f\u0930\u092e\u093f\u0928\u093f\u0938\u094d\u091f\u093f\u0915) \u0930\u0942\u092a \u0915\u093f\u0938\u094d\u092e\u0924 \u0915\u094b \u092a\u0942\u0930\u0940 \u0924\u0930\u0939 \u0939\u091f\u093e \u0926\u0947\u0924\u0947 \u0939\u0948\u0902 \u0914\u0930 \u092c\u0938 \u090f\u0915 \u0910\u0938\u093e \u0928\u093f\u092f\u092e \u092a\u0932\u091f\u0924\u0947 \u0939\u0948\u0902 \u091c\u094b \u0939\u092e\u0947\u0936\u093e \u0938\u091a \u0930\u0939\u0924\u093e \u0939\u0948\u0964"},zh:{about:"PRL\u662f\u4e00\u4e2a\u6982\u7387\u6027\u53cd\u8f6c\u5b66\u4e60\u4efb\u52a1\u3002\u4f60\u9762\u524d\u6709\u4e24\u4e2a\u9009\u9879\uff0c\u6bcf\u4e00\u8f6e\u9009\u4e00\u4e2a\uff1b\u8f83\u597d\u7684\u90a3\u4e2a\u9009\u9879\u5927\u591a\u6570\u65f6\u5019\u4f1a\u7ed9\u4f60\u56de\u62a5\uff0c\u4f46\u5e76\u975e\u6bcf\u6b21\u90fd\u7ed9\uff0c\u6240\u4ee5\u4f60\u8981\u901a\u8fc7\u53cd\u590d\u8bd5\u9519\u6765\u5b66\u4f1a\u5f53\u524d\u54ea\u4e00\u4e2a\u662f\u300e\u597d\u300f\u7684\u3002\u89c4\u5219\u4f1a\u6beb\u65e0\u9884\u8b66\u5730\u7ffb\u8f6c\uff0c\u53e6\u4e00\u4e2a\u9009\u9879\u53d8\u6210\u66f4\u597d\u7684\u90a3\u4e2a\uff0c\u800c\u4f60\u7684\u4efb\u52a1\u5c31\u662f\u5bdf\u89c9\u8fd9\u4e00\u53d8\u5316\u5e76\u5207\u6362\uff0c\u800c\u4e0d\u662f\u56fa\u6267\u5730\u5b88\u7740\u90a3\u4e2a\u66fe\u7ecf\u7ba1\u7528\u7684\u9009\u9879\u3002",benefit:"\u5b83\u8bad\u7ec3\u8ba4\u77e5\u7075\u6d3b\u6027\u4ee5\u53ca\u4e0d\u786e\u5b9a\u60c5\u5883\u4e0b\u7531\u53cd\u9988\u9a71\u52a8\u7684\u5b66\u4e60\uff1a\u5728\u4e00\u6761\u89c4\u5219\u8fd8\u5728\u7ed9\u4f60\u56de\u62a5\u65f6\u5b88\u4f4f\u5b83\uff0c\u628a\u4e00\u6b21\u771f\u6b63\u7684\u53cd\u8f6c\u548c\u4e00\u8fde\u4e32\u7684\u574f\u8fd0\u6c14\u533a\u5206\u5f00\u6765\uff0c\u5e76\u5728\u66f4\u65b0\u9009\u62e9\u65f6\u4e0d\u4f1a\u56e0\u4e3a\u5355\u4e00\u7684\u8bef\u5bfc\u6027\u7ed3\u679c\u800c\u53cd\u5e94\u8fc7\u5ea6\u3002",history:"\u8fd9\u4e2a\u60f3\u6cd5\u6e90\u4e8e20\u4e16\u7eaa\u4e2d\u53f6\u7684\u52a8\u7269\u5b66\u4e60\u7814\u7a76\u2014\u2014\u5148\u6559\u4f1a\u52a8\u7269\u4e00\u4e2a\u7b80\u5355\u7684\u8fa8\u522b\uff0c\u7136\u540e\u628a\u5956\u52b1\u7684\u5173\u8054\u53cd\u8f6c\u8fc7\u6765\uff0c\u770b\u5b83\u4eec\u80fd\u591a\u5feb\u91cd\u65b0\u5b66\u4f1a\u3002\u4f9b\u4eba\u7c7b\u4f7f\u7528\u7684\u6982\u7387\u7248\u672c\u57282000\u5e74\u4ee3\u521d\u7684\u8ba4\u77e5\u795e\u7ecf\u79d1\u5b66\u4e2d\u6210\u5f62\uff0c\u5f53\u65f6\u7814\u7a76\u8005\u52a0\u5165\u4e86\u5e26\u566a\u58f0\u7684\u53cd\u9988\uff0c\u4ee5\u66f4\u597d\u5730\u6a21\u62df\u73b0\u5b9e\u4e16\u754c\u7684\u4e0d\u786e\u5b9a\u6027\uff0c\u5e76\u63a2\u67e5\u5927\u8111\u5982\u4f55\u5e94\u5bf9\u4e0d\u65ad\u53d8\u5316\u7684\u89c4\u5219\u3002",creator:"\u5b83\u6ca1\u6709\u5355\u4e00\u7684\u53d1\u660e\u8005\u3002\u53cd\u8f6c\u5b66\u4e60\u6e90\u81ea20\u4e16\u7eaa40\u300150\u5e74\u4ee3\u8fa8\u522b\u53cd\u8f6c\u7814\u7a76\u7684\u884c\u4e3a\u4e3b\u4e49\u4f20\u7edf\uff0c\u4e0eHarry Harlow\u3001Kendler\u592b\u5987\u4ee5\u53caN. J. Mackintosh\u7b49\u7814\u7a76\u8005\u76f8\u5173\u8054\u3002\u7528\u4e8e\u4eba\u7c7b\u8111\u6210\u50cf\u7684\u73b0\u4ee3\u6982\u7387\u53cd\u8f6c\u4efb\u52a1\u901a\u5e38\u5f52\u529f\u4e8e\u5251\u6865\u7684Roshan Cools\u3001Luke Clark\u53ca\u5176\u540c\u4e8b\u57282002\u5e74\u524d\u540e\u7684\u5de5\u4f5c\uff0c\u4ed6\u4eec\u662f\u5728\u90a3\u6761\u66f4\u53e4\u8001\u7684\u8109\u7edc\u4e0a\u52a0\u4ee5\u53d1\u5c55\uff0c\u800c\u975e\u5f00\u521b\u5b83\u3002",methods:"\u628a\u5355\u6b21\u7684\u574f\u7ed3\u679c\u5f53\u6210\u566a\u58f0\uff0c\u800c\u4e0d\u662f\u8bc1\u636e\uff1a\u53ea\u6709\u5f53\u4f60\u539f\u672c\u8ba4\u4e3a\u6700\u4f73\u7684\u90a3\u4e2a\u9009\u9879\u8fde\u7eed\u597d\u51e0\u6b21\u5931\u624b\u4e4b\u540e\uff0c\u624d\u80fd\u65ad\u5b9a\u89c4\u5219\u5df2\u7ecf\u7ffb\u8f6c\u3002\u5728\u5fc3\u91cc\u5bf9\u8fd1\u671f\u7ed3\u679c\u4fdd\u6301\u4e00\u4e2a\u5927\u81f4\u7684\u8ba1\u6570\uff0c\u800c\u4e0d\u662f\u5bf9\u6700\u540e\u4e00\u6b21\u7ed3\u679c\u505a\u51fa\u53cd\u5e94\uff1b\u4e00\u65e6\u4f60\u5207\u6362\u4e86\uff0c\u5c31\u5728\u65b0\u7684\u9009\u62e9\u4e0a\u575a\u6301\u8db3\u591f\u4e45\u4ee5\u786e\u8ba4\u5b83\uff0c\u7136\u540e\u518d\u53bb\u6000\u7591\u3002",duration:"\u77ed\u800c\u89c4\u5f8b\u7684\u7ec3\u4e60\u6548\u679c\u6700\u597d\uff1a\u5927\u7ea65\u523010\u5206\u949f\uff0c\u6bcf\u5468\u51e0\u6b21\u3002\u8fd9\u91cc\u953b\u70bc\u7684\u6280\u80fd\u662f\u5feb\u901f\u66f4\u65b0\uff0c\u6240\u4ee5\u51e0\u4e2a\u77ed\u56de\u5408\u80dc\u8fc7\u4e00\u6b21\u6f2b\u957f\u7684\u786c\u5237\u2014\u2014\u75b2\u52b3\u4f1a\u8ba9\u4f60\u8981\u4e48\u8fc7\u4e8e\u795e\u7ecf\u8d28\uff0c\u8981\u4e48\u8fc7\u4e8e\u50f5\u5316\u3002",research:"\u8bc1\u636e\u6700\u5f3a\u7684\u662f\u90a3\u4e2a\u663e\u800c\u6613\u89c1\u7684\u90e8\u5206\uff1a\u968f\u7740\u7ec3\u4e60\uff0c\u4f60\u4f1a\u8d8a\u6765\u8d8a\u64c5\u957f\u8fd9\u4e2a\u4efb\u52a1\u672c\u8eab\uff0c\u4e5f\u8d8a\u6765\u8d8a\u80fd\u628a\u771f\u6b63\u7684\u89c4\u5219\u53d8\u5316\u548c\u5012\u9709\u7684\u8fde\u8d25\u533a\u5206\u5f00\u6765\uff0c\u800c\u4e14\u8be5\u4efb\u52a1\u5728\u4e34\u5e8a\u4e0e\u795e\u7ecf\u79d1\u5b66\u7814\u7a76\u4e2d\u53ef\u9760\u5730\u53cd\u6620\u4e86\u4e0d\u540c\u4eba\u7fa4\u5728\u7075\u6d3b\u6027\u4e0a\u7684\u5dee\u5f02\u3002\u81f3\u4e8e\u8fd9\u7c7b\u8bad\u7ec3\u80fd\u5e7f\u6cdb\u8fc1\u79fb\u5230\u65e5\u5e38\u51b3\u7b56\u6216\u4e00\u822c\u300e\u8ba4\u77e5\u7075\u6d3b\u6027\u300f\u7684\u8bf4\u6cd5\u5219\u5f88\u8584\u5f31\u4e14\u6709\u4e89\u8bae\uff0c\u66f4\u5bbd\u6cdb\u7684\u5065\u8111\u8bad\u7ec3\u6587\u732e\u4e5f\u51e0\u4e4e\u6ca1\u6709\u7406\u7531\u8ba9\u4eba\u671f\u5f85\u8fdc\u8fc1\u79fb\uff0c\u6240\u4ee5\u5bf9\u4efb\u4f55\u5b8f\u5927\u7684\u627f\u8bfa\u90fd\u8981\u4fdd\u6301\u8c28\u614e\u3002",rec:"\u5728\u5207\u6362\u4e4b\u524d\uff0c\u5148\u95ee\u95ee\u81ea\u5df1\uff1a\u4f60\u7a76\u7adf\u770b\u5230\u7684\u662f\u4e00\u8fde\u4e32\u5931\u8d25\u7684\u6a21\u5f0f\uff0c\u8fd8\u662f\u4ec5\u4ec5\u4e00\u6b21\u5012\u9709\u7684\u7ed3\u679c\uff1f\u53ea\u6709\u5f53\u8bc1\u636e\u7d2f\u79ef\u8d77\u6765\u65f6\u624d\u7ffb\u8f6c\u3002",faq:[["\u4e3a\u4ec0\u4e48\u6211\u9009\u4e86\u300e\u6b63\u786e\u300f\u7684\u9009\u9879\u5374\u8fd8\u662f\u8f93\u4e86\uff1f","\u56e0\u4e3a\u597d\u9009\u9879\u53ea\u662f\u5927\u591a\u6570\u65f6\u5019\u7ed9\u56de\u62a5\uff0c\u800c\u4e0d\u662f\u6bcf\u6b21\u90fd\u7ed9\u3002\u5355\u6b21\u7684\u8f93\u5f80\u5f80\u53ea\u662f\u566a\u58f0\uff1b\u89c4\u5219\u672a\u5fc5\u5df2\u7ecf\u53cd\u8f6c\u3002"],["\u6211\u600e\u4e48\u77e5\u9053\u89c4\u5219\u5230\u5e95\u4ec0\u4e48\u65f6\u5019\u7ffb\u8f6c\u4e86\uff1f","\u53bb\u627e\u90a3\u4e2a\u66fe\u7ecf\u7ba1\u7528\u7684\u9009\u62e9\u8fde\u7eed\u51fa\u73b0\u7684\u51e0\u6b21\u7cdf\u7cd5\u7ed3\u679c\uff0c\u800c\u4e0d\u662f\u5355\u4e00\u7684\u574f\u7ed3\u679c\u3002\u4e00\u65e6\u5931\u624b\u624e\u5806\u51fa\u73b0\uff0c\u90a3\u5c31\u662f\u4f60\u8be5\u5207\u6362\u7684\u4fe1\u53f7\u3002"],["\u8fd9\u4f1a\u8ba9\u6211\u5728\u73b0\u5b9e\u751f\u6d3b\u4e2d\u66f4\u7075\u6d3b\u5417\uff1f","\u5b83\u4e00\u5b9a\u4f1a\u8ba9\u4f60\u5728\u8fd9\u4e2a\u4efb\u52a1\u4ee5\u53ca\u7c7b\u4f3c\u4efb\u52a1\u4e0a\u505a\u5f97\u66f4\u597d\u3002\u80fd\u5426\u5e7f\u6cdb\u8fc1\u79fb\u5230\u65e5\u5e38\u51b3\u7b56\u5e76\u6ca1\u6709\u5f97\u5230\u5145\u5206\u652f\u6301\uff0c\u6240\u4ee5\u5c3d\u7ba1\u4eab\u53d7\u8fd9\u4efd\u7ec3\u4e60\uff0c\u4f46\u522b\u6307\u671b\u5b83\u80fd\u6539\u53d8\u4eba\u751f\u3002"]],variants:"\u5404\u79cd\u53d8\u4f53\u901a\u8fc7\u8c03\u6574\u597d\u9009\u9879\u7684\u53ef\u9760\u7a0b\u5ea6\u6765\u6539\u53d8\u96be\u5ea6\uff08\u4f8b\u598280/20\u5bf9\u6bd4\u566a\u58f0\u66f4\u5927\u768470/30\uff09\u3001\u53cd\u8f6c\u53d1\u751f\u7684\u9891\u7387\u3001\u4f60\u8ffd\u8e2a\u7684\u662f\u4e24\u4e2a\u8fd8\u662f\u591a\u4e2a\u9009\u9879\uff0c\u4ee5\u53ca\u53cd\u9988\u662f\u4ee5\u5956\u52b1\u3001\u4ee5\u635f\u5931\u8fd8\u662f\u4e24\u8005\u517c\u6709\u7684\u5f62\u5f0f\u5448\u73b0\u3002\u786e\u5b9a\u6027\u7248\u672c\u5219\u5b8c\u5168\u53bb\u6389\u8fd0\u6c14\u6210\u5206\uff0c\u5355\u7eaf\u7ffb\u8f6c\u4e00\u6761\u59cb\u7ec8\u6210\u7acb\u7684\u89c4\u5219\u3002"}},proofreading:{ru:{about:"\xab\u041a\u043e\u0440\u0440\u0435\u043a\u0442\u043e\u0440: \u0424\u043e\u043a\u0443\u0441\xbb \u2014 \u044d\u0442\u043e \u0437\u0430\u0434\u0430\u0447\u0430 \u043d\u0430 \u0432\u044b\u0447\u0451\u0440\u043a\u0438\u0432\u0430\u043d\u0438\u0435: \u044d\u043a\u0440\u0430\u043d \u0437\u0430\u043f\u043e\u043b\u043d\u0435\u043d \u043f\u043b\u043e\u0442\u043d\u044b\u043c \u043f\u043e\u043b\u0435\u043c \u043f\u043e\u0445\u043e\u0436\u0438\u0445 \u0434\u0440\u0443\u0433 \u043d\u0430 \u0434\u0440\u0443\u0433\u0430 \u0441\u0438\u043c\u0432\u043e\u043b\u043e\u0432, \u0430 \u0432\u044b \u043f\u043e\u0441\u0442\u0440\u043e\u0447\u043d\u043e \u043f\u0440\u043e\u0441\u043c\u0430\u0442\u0440\u0438\u0432\u0430\u0435\u0442\u0435 \u0435\u0433\u043e \u0438 \u043e\u0442\u043c\u0435\u0447\u0430\u0435\u0442\u0435 \u0442\u043e\u043b\u044c\u043a\u043e \u0442\u0435, \u0447\u0442\u043e \u043f\u043e\u0434\u0445\u043e\u0434\u044f\u0442 \u043f\u043e\u0434 \u0437\u0430\u0434\u0430\u043d\u043d\u043e\u0435 \u043f\u0440\u0430\u0432\u0438\u043b\u043e, \u043f\u0440\u043e\u043f\u0443\u0441\u043a\u0430\u044f \u0432\u0441\u0451 \u043e\u0441\u0442\u0430\u043b\u044c\u043d\u043e\u0435. \u041f\u043e \u0441\u0443\u0442\u0438 \u044d\u0442\u043e \u0446\u0438\u0444\u0440\u043e\u0432\u0430\u044f \u0432\u0435\u0440\u0441\u0438\u044f \u0440\u0430\u0431\u043e\u0442\u044b \u043a\u043e\u0440\u0440\u0435\u043a\u0442\u043e\u0440\u0430, \u0432\u044b\u0438\u0441\u043a\u0438\u0432\u0430\u044e\u0449\u0435\u0433\u043e \u043e\u0434\u043d\u0443 \u043a\u043e\u043d\u043a\u0440\u0435\u0442\u043d\u0443\u044e \u0431\u0443\u043a\u0432\u0443: \u043d\u0443\u0436\u043d\u043e \u0438\u0434\u0442\u0438 \u043a\u0430\u043a \u043c\u043e\u0436\u043d\u043e \u0431\u044b\u0441\u0442\u0440\u0435\u0435, \u043d\u0435 \u043f\u0440\u043e\u043f\u0443\u0441\u043a\u0430\u044f \u043d\u0443\u0436\u043d\u044b\u0435 \u0437\u043d\u0430\u043a\u0438 \u0438 \u043d\u0435 \u0437\u0430\u0434\u0435\u0432\u0430\u044f \u043b\u0438\u0448\u043d\u0438\u0435.",benefit:"\u0422\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u0438\u0437\u0431\u0438\u0440\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0435 \u0438 \u0443\u0441\u0442\u043e\u0439\u0447\u0438\u0432\u043e\u0435 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435, \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u0433\u043e \u043f\u043e\u0438\u0441\u043a\u0430 \u0438 \u043a\u043e\u043d\u0446\u0435\u043d\u0442\u0440\u0430\u0446\u0438\u044e \u0432 \u0443\u0441\u043b\u043e\u0432\u0438\u044f\u0445 \u043d\u0435\u0445\u0432\u0430\u0442\u043a\u0438 \u0432\u0440\u0435\u043c\u0435\u043d\u0438, \u0430 \u0437\u0430\u043e\u0434\u043d\u043e \u0441\u0430\u043c\u043e\u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044c \u2014 \u0443\u043c\u0435\u043d\u0438\u0435 \u0440\u0430\u0437 \u0437\u0430 \u0440\u0430\u0437\u043e\u043c \u043f\u0440\u043e\u043f\u0443\u0441\u043a\u0430\u0442\u044c \u043e\u0431\u043c\u0430\u043d\u0447\u0438\u0432\u043e \u043f\u043e\u0445\u043e\u0436\u0438\u0435 \u043e\u0442\u0432\u043b\u0435\u043a\u0430\u044e\u0449\u0438\u0435 \u0441\u0438\u043c\u0432\u043e\u043b\u044b, \u0430 \u043d\u0435 \u043e\u0442\u043c\u0435\u0447\u0430\u0442\u044c \u0438\u0445 \u043f\u043e \u0438\u043d\u0435\u0440\u0446\u0438\u0438.",history:"\u0417\u0430\u0434\u0430\u0447\u0438 \u043d\u0430 \u0432\u044b\u0447\u0451\u0440\u043a\u0438\u0432\u0430\u043d\u0438\u0435 \u2014 \u043e\u0434\u0438\u043d \u0438\u0437 \u0441\u0442\u0430\u0440\u0435\u0439\u0448\u0438\u0445 \u0438\u043d\u0441\u0442\u0440\u0443\u043c\u0435\u043d\u0442\u043e\u0432 \u0432 \u0438\u0437\u0443\u0447\u0435\u043d\u0438\u0438 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f. \u0424\u0440\u0430\u043d\u0446\u0443\u0437\u0441\u043a\u0438\u0439 \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433 \u0411\u0435\u043d\u0436\u0430\u043c\u0435\u043d \u0411\u0443\u0440\u0434\u043e\u043d \u043f\u0440\u0438\u043c\u0435\u043d\u044f\u043b \u0432\u044b\u0447\u0451\u0440\u043a\u0438\u0432\u0430\u043d\u0438\u0435 \u0431\u0443\u043a\u0432 \u0435\u0449\u0451 \u0432 1890-\u0445, \u0447\u0442\u043e\u0431\u044b \u0438\u0437\u0443\u0447\u0430\u0442\u044c \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u0435 \u0440\u0430\u0437\u043b\u0438\u0447\u0435\u043d\u0438\u0435, \u0422\u0443\u043b\u0443\u0437 \u0438 \u041f\u044c\u0435\u0440\u043e\u043d \u043e\u043f\u0443\u0431\u043b\u0438\u043a\u043e\u0432\u0430\u043b\u0438 \u0441\u0432\u043e\u0439 \u0432\u0430\u0440\u0438\u0430\u043d\u0442 \u0432 1904 \u0433\u043e\u0434\u0443, \u0430 \u043f\u043e\u0437\u0436\u0435 \u044d\u0442\u043e\u0442 \u0444\u043e\u0440\u043c\u0430\u0442 \u0440\u0430\u0437\u043e\u0448\u0451\u043b\u0441\u044f \u043f\u043e \u043a\u043b\u0438\u043d\u0438\u0447\u0435\u0441\u043a\u043e\u0439 \u043d\u0435\u0439\u0440\u043e\u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u0438 \u043a\u0430\u043a \u0431\u044b\u0441\u0442\u0440\u044b\u0439 \u0431\u043b\u0430\u043d\u043a\u043e\u0432\u044b\u0439 \u0441\u043f\u043e\u0441\u043e\u0431 \u043e\u0446\u0435\u043d\u0438\u0442\u044c \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435, \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0439 \u043f\u043e\u0438\u0441\u043a \u0438 \u0438\u0433\u043d\u043e\u0440\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u0435 \u0447\u0430\u0441\u0442\u0438 \u043f\u043e\u043b\u044f \u0437\u0440\u0435\u043d\u0438\u044f.",creator:"\u0415\u0434\u0438\u043d\u043e\u0433\u043e \u0430\u0432\u0442\u043e\u0440\u0430 \u043d\u0435\u0442; \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u0435 \u0432\u044b\u0440\u043e\u0441\u043b\u043e \u0438\u0437 \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u0438 \u0437\u0430\u0434\u0430\u0447 \u043d\u0430 \u0432\u044b\u0447\u0451\u0440\u043a\u0438\u0432\u0430\u043d\u0438\u0435, \u043a\u043e\u0442\u043e\u0440\u0443\u044e \u0437\u0430\u043b\u043e\u0436\u0438\u043b\u0438 \u0411\u0443\u0440\u0434\u043e\u043d (1890-\u0435) \u0438 \u0422\u0443\u043b\u0443\u0437 \u0441 \u041f\u044c\u0435\u0440\u043e\u043d\u043e\u043c (1904). \u0421\u0430\u043c\u044b\u0439 \u0438\u0437\u0432\u0435\u0441\u0442\u043d\u044b\u0439 \u0441\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u044b\u0439 \u043f\u043e\u0442\u043e\u043c\u043e\u043a \u2014 \u0442\u0435\u0441\u0442 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f d2 \u043d\u0435\u043c\u0435\u0446\u043a\u043e\u0433\u043e \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0430 \u0420\u043e\u043b\u044c\u0444\u0430 \u0411\u0440\u0438\u043a\u0435\u043d\u043a\u0430\u043c\u043f\u0430, \u0432\u043f\u0435\u0440\u0432\u044b\u0435 \u0438\u0437\u0434\u0430\u043d\u043d\u044b\u0439 \u0432 1962 \u0433\u043e\u0434\u0443 (\u043f\u043e\u0437\u0436\u0435 \u043f\u0435\u0440\u0435\u0440\u0430\u0431\u043e\u0442\u0430\u043d \u043a\u0430\u043a d2-R); \u0438\u043c\u0435\u043d\u043d\u043e \u043d\u0430 \u043d\u0435\u0433\u043e \u0442\u0430\u043a\u0430\u044f \u0438\u0433\u0440\u0430 \u043f\u043e\u0445\u043e\u0436\u0430 \u0431\u043e\u043b\u044c\u0448\u0435 \u0432\u0441\u0435\u0433\u043e.",methods:"\u041f\u0440\u043e\u0441\u043c\u0430\u0442\u0440\u0438\u0432\u0430\u0439\u0442\u0435 \u043f\u043e\u043b\u0435 \u0432 \u043e\u0434\u043d\u043e\u043c \u0438 \u0442\u043e\u043c \u0436\u0435 \u043f\u043e\u0440\u044f\u0434\u043a\u0435 \u2014 \u0441\u043b\u0435\u0432\u0430 \u043d\u0430\u043f\u0440\u0430\u0432\u043e \u0438 \u0441\u0432\u0435\u0440\u0445\u0443 \u0432\u043d\u0438\u0437, \u0430 \u043d\u0435 \u043f\u0440\u044b\u0433\u0430\u0439\u0442\u0435 \u043f\u043e \u043d\u0435\u043c\u0443 \u043d\u0430\u0443\u0433\u0430\u0434. \u0417\u0430\u0444\u0438\u043a\u0441\u0438\u0440\u0443\u0439\u0442\u0435 \u043f\u0440\u0430\u0432\u0438\u043b\u043e \u043f\u043e\u0438\u0441\u043a\u0430 \u0432 \u0433\u043e\u043b\u043e\u0432\u0435 \u0434\u043e \u0441\u0442\u0430\u0440\u0442\u0430, \u0447\u0442\u043e\u0431\u044b \u043d\u0435 \u043f\u0435\u0440\u0435\u0447\u0438\u0442\u044b\u0432\u0430\u0442\u044c \u0435\u0433\u043e \u043f\u043e\u0441\u0440\u0435\u0434\u0438 \u0441\u0442\u0440\u043e\u043a\u0438, \u0438 \u0434\u0435\u0440\u0436\u0438\u0442\u0435 \u0440\u043e\u0432\u043d\u044b\u0439 \u0440\u0438\u0442\u043c, \u0433\u0434\u0435 \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u044c \u0438\u0434\u0451\u0442 \u043f\u0435\u0440\u0432\u043e\u0439, \u0430 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u043d\u0430\u0440\u0430\u0449\u0438\u0432\u0430\u0435\u0442\u0441\u044f \u0443\u0436\u0435 \u043f\u043e\u0432\u0435\u0440\u0445 \u043d\u0435\u0451. \u041c\u043e\u043c\u0435\u043d\u0442, \u043a\u043e\u0433\u0434\u0430 \u0432\u044b \u043d\u0430\u0447\u0438\u043d\u0430\u0435\u0442\u0435 \u0437\u0430\u043c\u0435\u0434\u043b\u044f\u0442\u044c\u0441\u044f \u0438 \u043f\u0440\u043e\u043f\u0443\u0441\u043a\u0430\u0442\u044c \u0446\u0435\u043b\u0438, \u2014 \u044d\u0442\u043e \u0438 \u0435\u0441\u0442\u044c \u0442\u0430 \u0433\u0440\u0430\u043d\u044c, \u043a\u043e\u0442\u043e\u0440\u0443\u044e \u0441\u0442\u043e\u0438\u0442 \u0447\u0443\u0442\u044c-\u0447\u0443\u0442\u044c \u043f\u0440\u043e\u0434\u0430\u0432\u043b\u0438\u0432\u0430\u0442\u044c.",duration:"\u041b\u0443\u0447\u0448\u0435 \u0432\u0441\u0435\u0433\u043e \u0440\u0430\u0431\u043e\u0442\u0430\u044e\u0442 \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u0435 \u0447\u0430\u0441\u0442\u044b\u0435 \u043f\u043e\u0434\u0445\u043e\u0434\u044b: \u043f\u0440\u0438\u043c\u0435\u0440\u043d\u043e 5\u201310 \u043c\u0438\u043d\u0443\u0442 \u0432 \u0434\u0435\u043d\u044c, \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0440\u0430\u0437 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e. \u0412\u044b\u0447\u0451\u0440\u043a\u0438\u0432\u0430\u043d\u0438\u0435 \u0441\u0438\u043b\u044c\u043d\u043e \u0443\u0442\u043e\u043c\u043b\u044f\u0435\u0442 \u0441\u0438\u0441\u0442\u0435\u043c\u0443 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u043e\u0441\u0442\u0430\u043d\u0430\u0432\u043b\u0438\u0432\u0430\u0439\u0442\u0435\u0441\u044c, \u043a\u043e\u0433\u0434\u0430 \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u044c \u043d\u0430\u0447\u0438\u043d\u0430\u0435\u0442 \u043f\u043b\u044b\u0442\u044c, \u0430 \u043d\u0435 \u0434\u043e\u0436\u0438\u043c\u0430\u0439\u0442\u0435 \u0434\u043b\u0438\u043d\u043d\u044b\u0439 \u0431\u043b\u043e\u043a \u0447\u0435\u0440\u0435\u0437 \u0441\u0438\u043b\u0443.",research:"\u0414\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u043d\u0435\u0435 \u0432\u0441\u0435\u0433\u043e \u0440\u043e\u0432\u043d\u043e \u0442\u043e, \u0447\u0435\u0433\u043e \u0438 \u0436\u0434\u0451\u0448\u044c: \u0441 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u043e\u0439 \u0432\u044b \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u0438 \u0442\u043e\u0447\u043d\u0435\u0435 \u0441\u043f\u0440\u0430\u0432\u043b\u044f\u0435\u0442\u0435\u0441\u044c \u0441 \u0441\u0430\u043c\u0438\u043c \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u043c \u043f\u043e\u0438\u0441\u043a\u043e\u043c \u0438 \u0432\u044b\u0447\u0451\u0440\u043a\u0438\u0432\u0430\u043d\u0438\u0435\u043c \u2014 \u043f\u043e\u044d\u0442\u043e\u043c\u0443 d2 \u0438 \u043f\u043e\u0445\u043e\u0436\u0438\u0435 \u0442\u0435\u0441\u0442\u044b \u0441\u0447\u0438\u0442\u0430\u044e\u0442\u0441\u044f \u043d\u0430\u0434\u0451\u0436\u043d\u044b\u043c\u0438 \u043a\u043b\u0438\u043d\u0438\u0447\u0435\u0441\u043a\u0438\u043c\u0438 \u043c\u0435\u0440\u0430\u043c\u0438 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f \u0438 \u043a\u043e\u043d\u0446\u0435\u043d\u0442\u0440\u0430\u0446\u0438\u0438. \u0410 \u0432\u043e\u0442 \u0437\u0430\u044f\u0432\u043b\u0435\u043d\u0438\u044f, \u0447\u0442\u043e \u0442\u0430\u043a\u0430\u044f \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0430 \u0434\u0430\u0451\u0442 \u0448\u0438\u0440\u043e\u043a\u0438\u0439 \u043f\u0440\u0438\u0440\u043e\u0441\u0442, \u043f\u043e\u0432\u044b\u0448\u0430\u0435\u0442 \u043e\u0431\u0449\u0438\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0438\u043b\u0438 \u0437\u0430\u0449\u0438\u0449\u0430\u0435\u0442 \u043e\u0442 \u043a\u043e\u0433\u043d\u0438\u0442\u0438\u0432\u043d\u043e\u0433\u043e \u0441\u043f\u0430\u0434\u0430, \u043a\u0443\u0434\u0430 \u0441\u043b\u0430\u0431\u0435\u0435: \u0432 \u043a\u043e\u0433\u043d\u0438\u0442\u0438\u0432\u043d\u043e\u043c \u0442\u0440\u0435\u043d\u0438\u043d\u0433\u0435 \u0442\u0430\u043a\u043e\u0439 \u0434\u0430\u043b\u044c\u043d\u0438\u0439 \u043f\u0435\u0440\u0435\u043d\u043e\u0441 \u043f\u0435\u0447\u0430\u043b\u044c\u043d\u043e \u0438\u0437\u0432\u0435\u0441\u0442\u0435\u043d \u0442\u0435\u043c, \u0447\u0442\u043e \u043f\u043e\u0447\u0442\u0438 \u043d\u0435 \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u0435\u0442\u0441\u044f, \u0442\u0430\u043a \u0447\u0442\u043e \u043a \u0433\u0440\u043e\u043c\u043a\u0438\u043c \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f\u043c \u0441\u0442\u043e\u0438\u0442 \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u044c\u0441\u044f \u043e\u0441\u0442\u043e\u0440\u043e\u0436\u043d\u043e.",rec:"\u0421\u043d\u0430\u0447\u0430\u043b\u0430 \u0434\u043e\u0431\u0438\u0432\u0430\u0439\u0442\u0435\u0441\u044c \u0447\u0438\u0441\u0442\u043e\u0439 \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u0438, \u0430 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u043f\u043e\u0434\u0442\u044f\u043d\u0435\u0442\u0441\u044f \u0441\u0430\u043c\u0430; \u0431\u044b\u0441\u0442\u0440\u044b\u0439 \u043f\u0440\u043e\u0445\u043e\u0434 \u0441 \u043a\u0443\u0447\u0435\u0439 \u043e\u0448\u0438\u0431\u043e\u0447\u043d\u044b\u0445 \u043d\u0430\u0436\u0430\u0442\u0438\u0439 \u0437\u0430\u043a\u0440\u0435\u043f\u043b\u044f\u0435\u0442 \u043d\u0435\u043f\u0440\u0430\u0432\u0438\u043b\u044c\u043d\u0443\u044e \u043f\u0440\u0438\u0432\u044b\u0447\u043a\u0443.",faq:[["\u0427\u0442\u043e \u0432\u0430\u0436\u043d\u0435\u0435 \u2014 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u0438\u043b\u0438 \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u044c?","\u0421\u043d\u0430\u0447\u0430\u043b\u0430 \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u044c. \u0422\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442\u0441\u044f \u0438\u043c\u0435\u043d\u043d\u043e \u043e\u0442\u0441\u0435\u0432 \u043e\u0442\u0432\u043b\u0435\u043a\u0430\u044e\u0449\u0438\u0445 \u0441\u0438\u043c\u0432\u043e\u043b\u043e\u0432 \u0431\u0435\u0437 \u043e\u0448\u0438\u0431\u043e\u043a, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u043c\u0435\u0434\u043b\u0435\u043d\u043d\u044b\u0439, \u043d\u043e \u0447\u0438\u0441\u0442\u044b\u0439 \u043f\u0440\u043e\u0445\u043e\u0434 \u043b\u0443\u0447\u0448\u0435 \u0431\u044b\u0441\u0442\u0440\u043e\u0433\u043e \u0441 \u043b\u0438\u0448\u043d\u0438\u043c\u0438 \u043d\u0430\u0436\u0430\u0442\u0438\u044f\u043c\u0438. \u0421\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u043d\u0430\u0440\u0430\u0441\u0442\u0430\u0435\u0442 \u0441\u0430\u043c\u0430, \u043a\u043e\u0433\u0434\u0430 \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u044c \u0441\u0442\u0430\u0431\u0438\u043b\u044c\u043d\u0430."],["\u0421\u0442\u0430\u043d\u0443 \u043b\u0438 \u044f \u0432\u043d\u0438\u043c\u0430\u0442\u0435\u043b\u044c\u043d\u0435\u0435 \u0432 \u043e\u0431\u044b\u0447\u043d\u043e\u0439 \u0436\u0438\u0437\u043d\u0438?","\u0417\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0439 \u043f\u043e\u0438\u0441\u043a \u0438 \u0432\u044b\u0447\u0451\u0440\u043a\u0438\u0432\u0430\u043d\u0438\u0435 \u044d\u0442\u043e \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u0435 \u0443\u043b\u0443\u0447\u0448\u0430\u0435\u0442 \u043d\u0430\u0434\u0451\u0436\u043d\u043e, \u0438 \u043c\u043d\u043e\u0433\u0438\u043c \u0441\u0430\u043c \u0440\u0438\u0442\u043c \u0441\u043e\u0441\u0440\u0435\u0434\u043e\u0442\u043e\u0447\u0435\u043d\u043d\u043e\u0433\u043e \u043f\u0440\u043e\u0441\u043c\u043e\u0442\u0440\u0430 \u0431\u0435\u0437 \u0441\u043f\u043e\u043b\u0437\u0430\u043d\u0438\u044f \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f \u043f\u0440\u0438\u044f\u0442\u0435\u043d. \u041d\u043e \u0448\u0438\u0440\u043e\u043a\u0438\u0439 \u043f\u0435\u0440\u0435\u043d\u043e\u0441 \u043d\u0430 \u043d\u0435 \u0441\u0432\u044f\u0437\u0430\u043d\u043d\u044b\u0435 \u0441 \u044d\u0442\u0438\u043c \u0437\u0430\u0434\u0430\u0447\u0438 \u0434\u043e\u043a\u0430\u0437\u0430\u043d \u0441\u043b\u0430\u0431\u043e, \u0442\u0430\u043a \u0447\u0442\u043e \u0441\u0447\u0438\u0442\u0430\u0439\u0442\u0435 \u044d\u0442\u043e \u0442\u043e\u0447\u0435\u0447\u043d\u043e\u0439 \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u043e\u0439 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f, \u0430 \u043d\u0435 \u0443\u043d\u0438\u0432\u0435\u0440\u0441\u0430\u043b\u044c\u043d\u044b\u043c \u043b\u0435\u043a\u0430\u0440\u0441\u0442\u0432\u043e\u043c \u043e\u0442 \u0440\u0430\u0441\u0441\u0435\u044f\u043d\u043d\u043e\u0441\u0442\u0438."],["\u0427\u0435\u043c \u044d\u0442\u043e \u043e\u0442\u043b\u0438\u0447\u0430\u0435\u0442\u0441\u044f \u043e\u0442 \u0442\u0430\u0431\u043b\u0438\u0446\u044b \u0428\u0443\u043b\u044c\u0442\u0435?","\u0412 \u0442\u0430\u0431\u043b\u0438\u0446\u0435 \u0428\u0443\u043b\u044c\u0442\u0435 \u043a\u0430\u0436\u0434\u044b\u0439 \u044d\u043b\u0435\u043c\u0435\u043d\u0442 \u043e\u0434\u0438\u043d \u0438 \u0435\u0433\u043e \u043d\u0430\u0445\u043e\u0434\u044f\u0442 \u0432 \u0437\u0430\u0434\u0430\u043d\u043d\u043e\u043c \u043f\u043e\u0440\u044f\u0434\u043a\u0435 \u2014 \u044d\u0442\u043e \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u043f\u043e\u043b\u0435 \u0437\u0440\u0435\u043d\u0438\u044f \u0432\u043e\u043a\u0440\u0443\u0433 \u043d\u0435\u043f\u043e\u0434\u0432\u0438\u0436\u043d\u043e\u0433\u043e \u0432\u0437\u0433\u043b\u044f\u0434\u0430. \u0417\u0434\u0435\u0441\u044c \u0436\u0435 \u043c\u043d\u043e\u0433\u0438\u0435 \u044d\u043b\u0435\u043c\u0435\u043d\u0442\u044b \u043f\u043e\u0445\u043e\u0436\u0438, \u0438 \u043a\u0430\u0436\u0434\u044b\u0439 \u043d\u0443\u0436\u043d\u043e \u0441\u0432\u0435\u0440\u044f\u0442\u044c \u0441 \u043f\u0440\u0430\u0432\u0438\u043b\u043e\u043c, \u0447\u0442\u043e \u0431\u043e\u043b\u044c\u0448\u0435 \u043d\u0430\u0433\u0440\u0443\u0436\u0430\u0435\u0442 \u043e\u0442\u0441\u0435\u0432 \u043e\u0442\u0432\u043b\u0435\u043a\u0430\u044e\u0449\u0438\u0445 \u0437\u043d\u0430\u043a\u043e\u0432 \u0438 \u0443\u043c\u0435\u043d\u0438\u0435 \u0443\u0434\u0435\u0440\u0436\u0430\u0442\u044c\u0441\u044f \u043e\u0442 \u043d\u0430\u0436\u0430\u0442\u0438\u044f \u043d\u0430 \u0434\u0432\u043e\u0439\u043d\u0438\u043a\u043e\u0432."]],variants:"\u0412\u0430\u0440\u0438\u0430\u043d\u0442\u044b \u043c\u0435\u043d\u044f\u044e\u0442 \u043f\u0440\u0430\u0432\u0438\u043b\u043e \u043f\u043e\u0438\u0441\u043a\u0430 (\u043e\u0434\u043d\u0430 \u0431\u0443\u043a\u0432\u0430, \u043f\u0430\u0440\u0430 \u0431\u0443\u043a\u0432, \u0444\u043e\u0440\u043c\u0430 \u0438\u043b\u0438 \u0446\u0432\u0435\u0442, \u043b\u0438\u0431\u043e \u0441\u0438\u043c\u0432\u043e\u043b \u0442\u043e\u043b\u044c\u043a\u043e \u0441 \u043e\u043f\u0440\u0435\u0434\u0435\u043b\u0451\u043d\u043d\u043e\u0439 \u043f\u043e\u043c\u0435\u0442\u043a\u043e\u0439), \u043f\u043b\u043e\u0442\u043d\u043e\u0441\u0442\u044c \u0438 \u0440\u0430\u0437\u043c\u0435\u0440 \u043f\u043e\u043b\u044f, \u0440\u0435\u0436\u0438\u043c \u0432\u0440\u0435\u043c\u0435\u043d\u0438 (\u0444\u0438\u043a\u0441\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u044b\u0439 \u0442\u0430\u0439\u043c\u0435\u0440 \u0438\u043b\u0438 \u0432 \u0441\u0432\u043e\u0451\u043c \u0442\u0435\u043c\u043f\u0435), \u0430 \u0442\u0430\u043a\u0436\u0435 \u0441\u0442\u0435\u043f\u0435\u043d\u044c \u043f\u043e\u0445\u043e\u0436\u0435\u0441\u0442\u0438 \u043e\u0442\u0432\u043b\u0435\u043a\u0430\u044e\u0449\u0438\u0445 \u0437\u043d\u0430\u043a\u043e\u0432 \u043d\u0430 \u0446\u0435\u043b\u044c \u2014 \u0447\u0435\u043c \u043e\u043d\u0438 \u0431\u043b\u0438\u0436\u0435, \u0442\u0435\u043c \u043f\u043e\u0438\u0441\u043a \u0442\u0440\u0443\u0434\u043d\u0435\u0435."},en:{about:"Proofread: Focus is a cancellation task: the screen fills with a dense field of similar-looking characters, and your job is to scan it line by line and tap only the targets that match a given rule while ignoring everything else. It is the digital version of a proofreader hunting for one specific letter, working as fast as you can without missing hits or tapping the wrong symbol.",benefit:"It trains selective and sustained attention, visual scanning speed, and concentration under time pressure, plus the impulse control to keep skipping the look-alike distractors instead of tapping them.",history:"Cancellation tasks are one of the oldest tools in attention research. The French psychologist Benjamin Bourdon used letter-cancellation in the 1890s to study visual discrimination, Toulouse and Pi\xe9ron published their version in 1904, and the format later spread through clinical neuropsychology as a quick paper-and-pencil measure of attention, scanning, and visual neglect.",creator:"There is no single inventor; the exercise comes from the cancellation-task tradition started by Bourdon (1890s) and Toulouse-Pi\xe9ron (1904). The best-known modern descendant is the d2 Test of Attention, created by the German psychologist Rolf Brickenkamp and first published in 1962 (later revised as the d2-R), which this kind of game most closely resembles.",methods:"Sweep in a fixed reading pattern, left to right and top to bottom, rather than jumping around the field at random. Lock the target rule in mind before you start so you are not re-reading it mid-line, and aim for a steady rhythm where accuracy comes first and speed builds on top of it. When you notice yourself slowing or missing hits, that fatigue point is exactly the edge worth pushing a little.",duration:"Short, frequent sessions work best: roughly 5 to 10 minutes a day, a few times a week. Cancellation work is tiring for the attention system, so stop when accuracy starts to drift rather than grinding through a long block.",research:"Evidence is strongest for exactly what you would expect: with practice you get faster and more accurate at visual search and cancellation tasks themselves, which is why the d2 and similar tests are trusted clinical measures of attention and concentration. Claims that this kind of drill produces broad gains, raises general intelligence, or prevents cognitive decline are far weaker; in cognitive training such far transfer is famously hard to demonstrate and mostly fails to hold up, so treat the grand promises with caution.",rec:"Chase clean accuracy first and let speed follow; a fast run riddled with wrong taps trains the wrong habit.",faq:[["Is it better to go fast or to be accurate?","Accuracy first. The skill being trained is filtering out distractors without errors, so a slower clean pass beats a fast one full of wrong taps. Speed grows naturally once your accuracy is solid."],["Will this make me more focused in everyday life?","It reliably makes you better at visual search and cancellation tasks, and many people find the focused, scan-without-drifting rhythm pleasant to practise. But broad transfer to unrelated tasks is not well proven, so treat it as targeted attention practice, not a general focus cure."],["How is this different from a Schulte table?","A Schulte table has one item of each kind and you find them in a set order, training the field of view around a fixed gaze. Here many items look alike and you must judge each one against a rule, which leans more on filtering distractors and resisting the urge to tap look-alikes."]],variants:"Variants change the target rule (one letter, a pair of letters, a shape or colour, or a character only when it carries a specific mark), the density and size of the field, whether the clock is fixed or self-paced, and whether distractors look more or less like the target to make the search harder."},es:{about:"Proofread: Focus es una tarea de cancelaci\xf3n: la pantalla se llena de un campo denso de caracteres parecidos entre s\xed, y tu tarea es recorrerlo l\xednea por l\xednea y tocar solo los objetivos que cumplen una regla dada, ignorando todo lo dem\xe1s. Es la versi\xf3n digital de un corrector que busca una letra concreta, trabajando lo m\xe1s r\xe1pido que puedas sin saltarte aciertos ni tocar el s\xedmbolo equivocado.",benefit:"Entrena la atenci\xf3n selectiva y sostenida, la velocidad de rastreo visual y la concentraci\xf3n bajo presi\xf3n de tiempo, adem\xe1s del control de impulsos necesario para seguir descartando los distractores parecidos en vez de tocarlos.",history:"Las tareas de cancelaci\xf3n son una de las herramientas m\xe1s antiguas de la investigaci\xf3n sobre la atenci\xf3n. El psic\xf3logo franc\xe9s Benjamin Bourdon us\xf3 la cancelaci\xf3n de letras en la d\xe9cada de 1890 para estudiar la discriminaci\xf3n visual, Toulouse y Pi\xe9ron publicaron su versi\xf3n en 1904, y el formato se extendi\xf3 despu\xe9s por la neuropsicolog\xeda cl\xednica como una medida r\xe1pida de papel y l\xe1piz de la atenci\xf3n, el rastreo y la negligencia visual.",creator:"No hay un \xfanico inventor; el ejercicio proviene de la tradici\xf3n de las tareas de cancelaci\xf3n iniciada por Bourdon (d\xe9cada de 1890) y Toulouse-Pi\xe9ron (1904). Su descendiente moderno m\xe1s conocido es el Test de Atenci\xf3n d2, creado por el psic\xf3logo alem\xe1n Rolf Brickenkamp y publicado por primera vez en 1962 (revisado m\xe1s tarde como d2-R), al que este tipo de juego m\xe1s se parece.",methods:"Barre siguiendo un patr\xf3n de lectura fijo, de izquierda a derecha y de arriba abajo, en lugar de saltar por el campo al azar. Fija bien la regla del objetivo en la mente antes de empezar para no estar reley\xe9ndola a mitad de l\xednea, y busca un ritmo estable en el que la precisi\xf3n vaya primero y la velocidad se construya encima. Cuando notes que te ralentizas o que se te escapan aciertos, ese punto de fatiga es justo el l\xedmite que vale la pena empujar un poco.",duration:"Lo que mejor funciona son sesiones cortas y frecuentes: unos 5 a 10 minutos al d\xeda, varias veces por semana. El trabajo de cancelaci\xf3n cansa el sistema atencional, as\xed que detente cuando la precisi\xf3n empiece a flaquear en lugar de forzar un bloque largo.",research:"La evidencia es m\xe1s s\xf3lida justo en lo que cabr\xeda esperar: con la pr\xe1ctica te vuelves m\xe1s r\xe1pido y m\xe1s preciso en la b\xfasqueda visual y en las propias tareas de cancelaci\xf3n, por eso el d2 y pruebas similares son medidas cl\xednicas fiables de la atenci\xf3n y la concentraci\xf3n. Las afirmaciones de que este tipo de ejercicio produce mejoras amplias, eleva la inteligencia general o previene el deterioro cognitivo son mucho m\xe1s d\xe9biles; en el entrenamiento cognitivo esa transferencia lejana es notoriamente dif\xedcil de demostrar y casi nunca se sostiene, as\xed que toma con cautela las grandes promesas.",rec:"Persigue primero una precisi\xf3n limpia y deja que la velocidad llegue despu\xe9s; una ronda r\xe1pida plagada de toques err\xf3neos entrena el h\xe1bito equivocado.",faq:[["\xbfEs mejor ir r\xe1pido o ser preciso?","Primero la precisi\xf3n. La destreza que se entrena es filtrar los distractores sin errores, as\xed que una pasada limpia y m\xe1s lenta vence a una r\xe1pida llena de toques err\xf3neos. La velocidad crece sola cuando tu precisi\xf3n es s\xf3lida."],["\xbfEsto me har\xe1 estar m\xe1s concentrado en la vida diaria?","De forma fiable te hace mejor en la b\xfasqueda visual y en las tareas de cancelaci\xf3n, y a mucha gente le resulta agradable practicar ese ritmo de rastrear sin distraerse. Pero la transferencia amplia a tareas no relacionadas no est\xe1 bien demostrada, as\xed que t\xf3malo como pr\xe1ctica espec\xedfica de atenci\xf3n, no como una cura general para la concentraci\xf3n."],["\xbfEn qu\xe9 se diferencia de una tabla de Schulte?","Una tabla de Schulte tiene un elemento de cada clase y los encuentras en un orden fijo, entrenando el campo de visi\xf3n alrededor de una mirada fija. Aqu\xed muchos elementos se parecen entre s\xed y debes juzgar cada uno frente a una regla, lo que recae m\xe1s en filtrar distractores y resistir el impulso de tocar los que se parecen."]],variants:"Las variantes cambian la regla del objetivo (una letra, un par de letras, una forma o un color, o un car\xe1cter solo cuando lleva una marca concreta), la densidad y el tama\xf1o del campo, si el reloj es fijo o a tu propio ritmo, y si los distractores se parecen m\xe1s o menos al objetivo para dificultar la b\xfasqueda."},de:{about:"Proofread: Focus ist eine Durchstreichaufgabe: Der Bildschirm f\xfcllt sich mit einem dichten Feld \xe4hnlich aussehender Zeichen, und du musst es Zeile f\xfcr Zeile absuchen und nur die Ziele antippen, die einer vorgegebenen Regel entsprechen, w\xe4hrend du alles andere ignorierst. Es ist die digitale Fassung eines Korrektors, der nach einem bestimmten Buchstaben jagt \u2013 so schnell wie m\xf6glich, ohne Treffer zu verpassen oder das falsche Zeichen anzutippen.",benefit:"Es trainiert selektive und anhaltende Aufmerksamkeit, die Geschwindigkeit des visuellen Absuchens und die Konzentration unter Zeitdruck \u2013 dazu die Impulskontrolle, die \xe4hnlich aussehenden Ablenker weiter zu \xfcberspringen, statt sie anzutippen.",history:"Durchstreichaufgaben geh\xf6ren zu den \xe4ltesten Werkzeugen der Aufmerksamkeitsforschung. Der franz\xf6sische Psychologe Benjamin Bourdon setzte in den 1890er-Jahren das Durchstreichen von Buchstaben ein, um die visuelle Unterscheidung zu untersuchen; Toulouse und Pi\xe9ron ver\xf6ffentlichten 1904 ihre Variante, und das Format verbreitete sich sp\xe4ter in der klinischen Neuropsychologie als schnelles Papier-und-Bleistift-Ma\xdf f\xfcr Aufmerksamkeit, Absuchen und visuellen Neglect.",creator:"Es gibt keinen einzelnen Erfinder; die \xdcbung entstammt der Tradition der Durchstreichaufgaben, die Bourdon (1890er) und Toulouse-Pi\xe9ron (1904) begr\xfcndeten. Der bekannteste moderne Nachfahre ist der d2-Aufmerksamkeitstest des deutschen Psychologen Rolf Brickenkamp, erstmals 1962 ver\xf6ffentlicht (sp\xe4ter \xfcberarbeitet als d2-R), dem diese Art von Spiel am n\xe4chsten kommt.",methods:"Suche in einem festen Lesemuster ab, von links nach rechts und von oben nach unten, statt willk\xfcrlich durch das Feld zu springen. Pr\xe4ge dir die Zielregel ein, bevor du startest, damit du sie nicht mitten in der Zeile erneut nachlesen musst, und ziele auf einen gleichm\xe4\xdfigen Rhythmus, bei dem Treffsicherheit an erster Stelle steht und das Tempo darauf aufbaut. Wenn du merkst, dass du langsamer wirst oder Treffer verpasst, ist genau dieser Erm\xfcdungspunkt die Grenze, die sich ein wenig zu verschieben lohnt.",duration:"Kurze, h\xe4ufige Sitzungen funktionieren am besten: etwa 5 bis 10 Minuten am Tag, ein paar Mal pro Woche. Durchstreichen erm\xfcdet das Aufmerksamkeitssystem, also h\xf6r auf, wenn die Treffsicherheit nachzulassen beginnt, statt dich durch einen langen Block zu qu\xe4len.",research:"Am besten belegt ist genau das, was man erwarten w\xfcrde: Mit \xdcbung wirst du in visueller Suche und Durchstreichaufgaben selbst schneller und genauer \u2013 deshalb gelten der d2 und \xe4hnliche Tests als verl\xe4ssliche klinische Ma\xdfe f\xfcr Aufmerksamkeit und Konzentration. Behauptungen, dass solches Training breite Verbesserungen bringt, die allgemeine Intelligenz steigert oder den geistigen Abbau verhindert, sind weit schw\xe4cher; ein solcher Ferntransfer ist im kognitiven Training bekanntlich schwer nachzuweisen und scheitert meist \u2013 gro\xdfe Versprechen also mit Vorsicht genie\xdfen.",rec:"Strebe zuerst saubere Treffsicherheit an und lass das Tempo folgen; ein schneller Durchgang voller Fehlklicks trainiert die falsche Gewohnheit.",faq:[["Ist es besser, schnell oder genau zu sein?","Genauigkeit zuerst. Trainiert wird das Herausfiltern von Ablenkern ohne Fehler \u2013 ein langsamer, sauberer Durchgang schl\xe4gt also einen schnellen voller Fehlklicks. Das Tempo w\xe4chst von selbst, sobald deine Treffsicherheit gefestigt ist."],["Macht mich das im Alltag konzentrierter?","Es macht dich verl\xe4sslich besser in visueller Suche und Durchstreichaufgaben, und viele empfinden den konzentrierten Rhythmus des Absuchens ohne Abschweifen als angenehm. Aber ein breiter Transfer auf unverwandte Aufgaben ist nicht gut belegt \u2013 betrachte es also als gezieltes Aufmerksamkeitstraining, nicht als allgemeines Konzentrationsmittel."],["Worin unterscheidet sich das von einer Schulte-Tabelle?","Eine Schulte-Tabelle enth\xe4lt jedes Element nur einmal, und du findest sie in fester Reihenfolge, was das Sichtfeld um einen fixierten Blick trainiert. Hier sehen viele Elemente gleich aus, und du musst jedes anhand einer Regel beurteilen, was st\xe4rker auf das Herausfiltern von Ablenkern und das Widerstehen gegen den Drang, \xc4hnliches anzutippen, setzt."]],variants:"Varianten \xe4ndern die Zielregel (ein Buchstabe, ein Buchstabenpaar, eine Form oder Farbe oder ein Zeichen nur dann, wenn es ein bestimmtes Merkmal tr\xe4gt), die Dichte und Gr\xf6\xdfe des Feldes, ob die Uhr fest l\xe4uft oder du das Tempo selbst bestimmst und ob die Ablenker dem Ziel mehr oder weniger \xe4hneln, um die Suche zu erschweren."},pt:{about:"Proofread: Focus \xe9 uma tarefa de cancelamento: a tela se enche de um campo denso de caracteres parecidos entre si, e seu trabalho \xe9 percorr\xea-lo linha por linha e tocar apenas os alvos que correspondem a uma regra dada, ignorando todo o resto. \xc9 a vers\xe3o digital de um revisor ca\xe7ando uma letra espec\xedfica, trabalhando o mais r\xe1pido poss\xedvel sem deixar alvos passarem nem tocar o s\xedmbolo errado.",benefit:"Treina a aten\xe7\xe3o seletiva e sustentada, a velocidade de varredura visual e a concentra\xe7\xe3o sob press\xe3o de tempo, al\xe9m do controle do impulso de continuar ignorando os distratores parecidos em vez de toc\xe1-los.",history:"As tarefas de cancelamento est\xe3o entre as ferramentas mais antigas da pesquisa sobre aten\xe7\xe3o. O psic\xf3logo franc\xeas Benjamin Bourdon usou o cancelamento de letras na d\xe9cada de 1890 para estudar a discrimina\xe7\xe3o visual, Toulouse e Pi\xe9ron publicaram sua vers\xe3o em 1904, e o formato depois se difundiu pela neuropsicologia cl\xednica como uma medida r\xe1pida, de papel e l\xe1pis, de aten\xe7\xe3o, varredura e neglig\xeancia visual.",creator:"N\xe3o h\xe1 um \xfanico inventor; o exerc\xedcio vem da tradi\xe7\xe3o das tarefas de cancelamento iniciada por Bourdon (d\xe9cada de 1890) e por Toulouse-Pi\xe9ron (1904). O descendente moderno mais conhecido \xe9 o Teste de Aten\xe7\xe3o d2, criado pelo psic\xf3logo alem\xe3o Rolf Brickenkamp e publicado pela primeira vez em 1962 (depois revisado como d2-R), que \xe9 o que esse tipo de jogo mais se aproxima.",methods:"Fa\xe7a a varredura em um padr\xe3o de leitura fixo, da esquerda para a direita e de cima para baixo, em vez de pular pelo campo ao acaso. Fixe bem a regra do alvo na cabe\xe7a antes de come\xe7ar, para n\xe3o ter de rel\xea-la no meio da linha, e busque um ritmo constante em que a precis\xe3o venha primeiro e a velocidade seja constru\xedda em cima dela. Quando voc\xea perceber que est\xe1 desacelerando ou deixando alvos passarem, esse ponto de fadiga \xe9 justamente o limite que vale a pena for\xe7ar um pouco.",duration:"Sess\xf5es curtas e frequentes funcionam melhor: cerca de 5 a 10 minutos por dia, algumas vezes por semana. O trabalho de cancelamento cansa o sistema de aten\xe7\xe3o, ent\xe3o pare quando a precis\xe3o come\xe7ar a oscilar, em vez de insistir num bloco longo.",research:"A evid\xeancia \xe9 mais forte exatamente para o que se esperaria: com a pr\xe1tica voc\xea fica mais r\xe1pido e mais preciso na busca visual e nas pr\xf3prias tarefas de cancelamento, e \xe9 por isso que o d2 e testes semelhantes s\xe3o medidas cl\xednicas confi\xe1veis de aten\xe7\xe3o e concentra\xe7\xe3o. As alega\xe7\xf5es de que esse tipo de exerc\xedcio produz ganhos amplos, eleva a intelig\xeancia geral ou previne o decl\xednio cognitivo s\xe3o bem mais fracas; no treino cognitivo, esse tipo de transfer\xeancia ampla \xe9 notoriamente dif\xedcil de demonstrar e na maioria das vezes n\xe3o se sustenta, ent\xe3o encare as grandes promessas com cautela.",rec:"Busque primeiro uma precis\xe3o limpa e deixe a velocidade vir depois; uma rodada r\xe1pida cheia de toques errados treina o h\xe1bito errado.",faq:[["\xc9 melhor ir r\xe1pido ou ser preciso?","Precis\xe3o primeiro. A habilidade que est\xe1 sendo treinada \xe9 filtrar os distratores sem erros, ent\xe3o uma passagem mais lenta e limpa vale mais do que uma r\xe1pida cheia de toques errados. A velocidade cresce naturalmente quando sua precis\xe3o est\xe1 s\xf3lida."],["Isso vai me deixar mais concentrado no dia a dia?","Ele melhora de forma confi\xe1vel a sua busca visual e o seu desempenho em tarefas de cancelamento, e muita gente acha agrad\xe1vel treinar esse ritmo focado de varrer sem se dispersar. Mas a transfer\xeancia ampla para tarefas n\xe3o relacionadas n\xe3o \xe9 bem comprovada, ent\xe3o encare-o como uma pr\xe1tica de aten\xe7\xe3o direcionada, n\xe3o como uma cura geral para a concentra\xe7\xe3o."],["Em que isso difere de uma tabela de Schulte?","A tabela de Schulte tem um item de cada tipo e voc\xea os encontra numa ordem definida, treinando o campo de vis\xe3o ao redor de um olhar fixo. Aqui muitos itens s\xe3o parecidos e voc\xea precisa julgar cada um diante de uma regra, o que depende mais de filtrar distratores e de resistir \xe0 vontade de tocar os parecidos."]],variants:"As variantes mudam a regra do alvo (uma letra, um par de letras, uma forma ou cor, ou um caractere s\xf3 quando ele traz uma marca espec\xedfica), a densidade e o tamanho do campo, se o rel\xf3gio \xe9 fixo ou no seu pr\xf3prio ritmo, e se os distratores se parecem mais ou menos com o alvo, para deixar a busca mais dif\xedcil."},hi:{about:"\u092a\u094d\u0930\u0942\u092b\u093c\u0930\u0940\u0921: \u092b\u093c\u094b\u0915\u0938 \u090f\u0915 \u0915\u0948\u0902\u0938\u093f\u0932\u0947\u0936\u0928 (\u091b\u093e\u0901\u091f-\u0928\u093f\u0915\u093e\u0932) \u0915\u093e\u0930\u094d\u092f \u0939\u0948: \u0938\u094d\u0915\u094d\u0930\u0940\u0928 \u090f\u0915 \u091c\u0948\u0938\u0947 \u0926\u093f\u0916\u0928\u0947 \u0935\u093e\u0932\u0947 \u0905\u0915\u094d\u0937\u0930\u094b\u0902 \u0915\u0947 \u0918\u0928\u0947 \u092e\u0948\u0926\u093e\u0928 \u0938\u0947 \u092d\u0930 \u091c\u093e\u0924\u0940 \u0939\u0948, \u0914\u0930 \u0906\u092a\u0915\u093e \u0915\u093e\u092e \u0939\u0948 \u0907\u0938\u0947 \u092a\u0902\u0915\u094d\u0924\u093f-\u0926\u0930-\u092a\u0902\u0915\u094d\u0924\u093f \u0916\u0902\u0917\u093e\u0932\u0928\u093e \u0914\u0930 \u092c\u093e\u0915\u0940 \u0938\u092c \u0915\u094b \u0928\u091c\u093c\u0930\u0905\u0902\u0926\u093e\u091c\u093c \u0915\u0930\u0924\u0947 \u0939\u0941\u090f \u0938\u093f\u0930\u094d\u092b\u093c \u0909\u0928 \u0932\u0915\u094d\u0937\u094d\u092f\u094b\u0902 \u092a\u0930 \u091f\u0948\u092a \u0915\u0930\u0928\u093e \u091c\u094b \u0926\u093f\u090f \u0917\u090f \u0928\u093f\u092f\u092e \u0938\u0947 \u092e\u0947\u0932 \u0916\u093e\u0924\u0947 \u0939\u0948\u0902\u0964 \u092f\u0939 \u090f\u0915 \u092a\u094d\u0930\u0942\u092b\u093c\u0930\u0940\u0921\u0930 \u0915\u093e \u0921\u093f\u091c\u093f\u091f\u0932 \u0930\u0942\u092a \u0939\u0948 \u091c\u094b \u0915\u093f\u0938\u0940 \u090f\u0915 \u0916\u093c\u093e\u0938 \u0905\u0915\u094d\u0937\u0930 \u0915\u0940 \u0924\u0932\u093e\u0936 \u092e\u0947\u0902 \u091c\u0941\u091f\u093e \u0939\u0948, \u0914\u0930 \u091c\u093f\u0924\u0928\u0940 \u0924\u0947\u091c\u093c\u0940 \u0938\u0947 \u0939\u094b \u0938\u0915\u0947 \u092c\u093f\u0928\u093e \u0915\u093f\u0938\u0940 \u0915\u094b \u091b\u094b\u0921\u093c\u0947 \u092f\u093e \u0917\u0932\u0924 \u091a\u093f\u0939\u094d\u0928 \u091b\u0941\u090f \u0915\u093e\u092e \u0915\u0930\u0924\u093e \u0939\u0948\u0964",benefit:"\u092f\u0939 \u091a\u092f\u0928\u093e\u0924\u094d\u092e\u0915 \u0914\u0930 \u0932\u0917\u093e\u0924\u093e\u0930 \u092c\u0928\u0947 \u0930\u0939\u0928\u0947 \u0935\u093e\u0932\u0947 \u0927\u094d\u092f\u093e\u0928, \u0926\u0943\u0936\u094d\u092f \u0916\u0902\u0917\u093e\u0932\u0928\u0947 \u0915\u0940 \u0917\u0924\u093f, \u0914\u0930 \u0938\u092e\u092f \u0915\u0947 \u0926\u092c\u093e\u0935 \u092e\u0947\u0902 \u090f\u0915\u093e\u0917\u094d\u0930\u0924\u093e \u0915\u094b \u0938\u093e\u0927\u0924\u093e \u0939\u0948, \u0938\u093e\u0925 \u0939\u0940 \u0909\u0938 \u0906\u0935\u0947\u0917-\u0928\u093f\u092f\u0902\u0924\u094d\u0930\u0923 \u0915\u094b \u092d\u0940 \u091c\u093f\u0938\u0938\u0947 \u0906\u092a \u092e\u093f\u0932\u0924\u0947-\u091c\u0941\u0932\u0924\u0947 \u092d\u094d\u0930\u093e\u092e\u0915 \u091a\u093f\u0939\u094d\u0928\u094b\u0902 \u092a\u0930 \u091f\u0948\u092a \u0915\u0930\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u0909\u0928\u094d\u0939\u0947\u0902 \u091b\u094b\u0921\u093c\u0924\u0947 \u0930\u0939\u0924\u0947 \u0939\u0948\u0902\u0964",history:"\u0915\u0948\u0902\u0938\u093f\u0932\u0947\u0936\u0928 \u0915\u093e\u0930\u094d\u092f \u0927\u094d\u092f\u093e\u0928-\u0905\u0928\u0941\u0938\u0902\u0927\u093e\u0928 \u0915\u0947 \u0938\u092c\u0938\u0947 \u092a\u0941\u0930\u093e\u0928\u0947 \u0914\u091c\u093c\u093e\u0930\u094b\u0902 \u092e\u0947\u0902 \u0938\u0947 \u090f\u0915 \u0939\u0948\u0902\u0964 \u092b\u093c\u094d\u0930\u093e\u0902\u0938\u0940\u0938\u0940 \u092e\u0928\u094b\u0935\u0948\u091c\u094d\u091e\u093e\u0928\u093f\u0915 \u092c\u0947\u0902\u091c\u093e\u092e\u093f\u0928 \u092c\u0942\u0930\u0926\u094b\u0902 (Benjamin Bourdon) \u0928\u0947 1890 \u0915\u0947 \u0926\u0936\u0915 \u092e\u0947\u0902 \u0926\u0943\u0936\u094d\u092f \u0935\u093f\u092d\u0947\u0926\u0928 \u0915\u0947 \u0905\u0927\u094d\u092f\u092f\u0928 \u0915\u0947 \u0932\u093f\u090f \u0905\u0915\u094d\u0937\u0930-\u0915\u0948\u0902\u0938\u093f\u0932\u0947\u0936\u0928 \u0915\u093e \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0915\u093f\u092f\u093e, \u091f\u0942\u0932\u0942\u091c\u093c \u0914\u0930 \u092a\u093f\u090f\u0930\u094b\u0902 (Toulouse \u0914\u0930 Pi\xe9ron) \u0928\u0947 1904 \u092e\u0947\u0902 \u0905\u092a\u0928\u093e \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u092a\u094d\u0930\u0915\u093e\u0936\u093f\u0924 \u0915\u093f\u092f\u093e, \u0914\u0930 \u092c\u093e\u0926 \u092e\u0947\u0902 \u092f\u0939 \u092a\u094d\u0930\u093e\u0930\u0942\u092a \u0927\u094d\u092f\u093e\u0928, \u0916\u0902\u0917\u093e\u0932\u0928\u0947 \u0914\u0930 \u0926\u0943\u0936\u094d\u092f \u0909\u092a\u0947\u0915\u094d\u0937\u093e \u0915\u0947 \u090f\u0915 \u091d\u091f\u092a\u091f \u0915\u093e\u0917\u091c\u093c-\u0915\u0932\u092e \u0935\u093e\u0932\u0947 \u092e\u093e\u092a \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u0928\u0948\u0926\u093e\u0928\u093f\u0915 \u0924\u0902\u0924\u094d\u0930\u093f\u0915\u093e-\u092e\u0928\u094b\u0935\u093f\u091c\u094d\u091e\u093e\u0928 \u092e\u0947\u0902 \u092b\u0948\u0932 \u0917\u092f\u093e\u0964",creator:"\u0907\u0938\u0915\u093e \u0915\u094b\u0908 \u090f\u0915 \u0906\u0935\u093f\u0937\u094d\u0915\u093e\u0930\u0915 \u0928\u0939\u0940\u0902 \u0939\u0948; \u092f\u0939 \u0905\u092d\u094d\u092f\u093e\u0938 \u092c\u0942\u0930\u0926\u094b\u0902 (1890 \u0915\u0947 \u0926\u0936\u0915) \u0914\u0930 \u091f\u0942\u0932\u0942\u091c\u093c-\u092a\u093f\u090f\u0930\u094b\u0902 (1904) \u0938\u0947 \u0936\u0941\u0930\u0942 \u0939\u0941\u0908 \u0915\u0948\u0902\u0938\u093f\u0932\u0947\u0936\u0928-\u0915\u093e\u0930\u094d\u092f \u092a\u0930\u0902\u092a\u0930\u093e \u0938\u0947 \u0906\u0924\u093e \u0939\u0948\u0964 \u0938\u092c\u0938\u0947 \u091c\u093e\u0928\u093e-\u092e\u093e\u0928\u093e \u0906\u0927\u0941\u0928\u093f\u0915 \u0935\u0902\u0936\u091c \u0939\u0948 d2 \u091f\u0947\u0938\u094d\u091f \u0911\u092b\u093c \u0905\u091f\u0947\u0902\u0936\u0928, \u091c\u093f\u0938\u0947 \u091c\u0930\u094d\u092e\u0928 \u092e\u0928\u094b\u0935\u0948\u091c\u094d\u091e\u093e\u0928\u093f\u0915 \u0930\u0949\u0932\u094d\u092b\u093c \u092c\u094d\u0930\u093f\u0915\u0947\u0928\u0915\u0948\u0902\u092a (Rolf Brickenkamp) \u0928\u0947 \u0930\u091a\u093e \u0914\u0930 \u092a\u0939\u0932\u0940 \u092c\u093e\u0930 1962 \u092e\u0947\u0902 \u092a\u094d\u0930\u0915\u093e\u0936\u093f\u0924 \u0915\u093f\u092f\u093e (\u092c\u093e\u0926 \u092e\u0947\u0902 d2-R \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u0938\u0902\u0936\u094b\u0927\u093f\u0924), \u0914\u0930 \u0907\u0938 \u0924\u0930\u0939 \u0915\u093e \u0916\u0947\u0932 \u0907\u0938\u0940 \u0938\u0947 \u0938\u092c\u0938\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u092e\u093f\u0932\u0924\u093e-\u091c\u0941\u0932\u0924\u093e \u0939\u0948\u0964",methods:"\u092e\u0948\u0926\u093e\u0928 \u092e\u0947\u0902 \u092f\u0939\u093e\u0901-\u0935\u0939\u093e\u0901 \u0915\u0942\u0926\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u090f\u0915 \u0924\u092f \u092a\u0920\u0928-\u0915\u094d\u0930\u092e \u092e\u0947\u0902 \u091d\u093e\u0921\u093c\u0942 \u092b\u0947\u0930\u0947\u0902, \u092c\u093e\u090f\u0901 \u0938\u0947 \u0926\u093e\u090f\u0901 \u0914\u0930 \u090a\u092a\u0930 \u0938\u0947 \u0928\u0940\u091a\u0947\u0964 \u0936\u0941\u0930\u0942 \u0915\u0930\u0928\u0947 \u0938\u0947 \u092a\u0939\u0932\u0947 \u0932\u0915\u094d\u0937\u094d\u092f-\u0928\u093f\u092f\u092e \u0915\u094b \u092e\u0928 \u092e\u0947\u0902 \u092a\u0915\u094d\u0915\u093e \u0915\u0930 \u0932\u0947\u0902 \u0924\u093e\u0915\u093f \u0906\u092a\u0915\u094b \u092a\u0902\u0915\u094d\u0924\u093f \u0915\u0947 \u092c\u0940\u091a \u092e\u0947\u0902 \u0909\u0938\u0947 \u0926\u094b\u092c\u093e\u0930\u093e \u0928 \u092a\u0922\u093c\u0928\u093e \u092a\u0921\u093c\u0947, \u0914\u0930 \u090f\u0915 \u0938\u094d\u0925\u093f\u0930 \u0932\u092f \u0930\u0916\u0947\u0902 \u091c\u0939\u093e\u0901 \u092a\u0939\u0932\u0947 \u0938\u091f\u0940\u0915\u0924\u093e \u0906\u090f \u0914\u0930 \u0917\u0924\u093f \u0909\u0938\u0915\u0947 \u090a\u092a\u0930 \u092c\u0928\u0924\u0940 \u091c\u093e\u090f\u0964 \u091c\u092c \u0906\u092a \u0916\u093c\u0941\u0926 \u0915\u094b \u0927\u0940\u092e\u093e \u092a\u0921\u093c\u0924\u093e \u092f\u093e \u0932\u0915\u094d\u0937\u094d\u092f \u091a\u0942\u0915\u0924\u093e \u092e\u0939\u0938\u0942\u0938 \u0915\u0930\u0947\u0902, \u0935\u0939\u0940 \u0925\u0915\u093e\u0928-\u092c\u093f\u0902\u0926\u0941 \u0920\u0940\u0915 \u0935\u0939 \u0915\u093f\u0928\u093e\u0930\u093e \u0939\u0948 \u091c\u093f\u0938\u0947 \u0925\u094b\u0921\u093c\u093e \u0927\u0915\u0947\u0932\u0928\u093e \u0938\u093e\u0930\u094d\u0925\u0915 \u0939\u0948\u0964",duration:"\u091b\u094b\u091f\u0947, \u092c\u093e\u0930-\u092c\u093e\u0930 \u0935\u093e\u0932\u0947 \u0938\u0924\u094d\u0930 \u0938\u092c\u0938\u0947 \u0905\u091a\u094d\u091b\u0947 \u0930\u0939\u0924\u0947 \u0939\u0948\u0902: \u0930\u094b\u091c\u093c \u0915\u0930\u0940\u092c 5 \u0938\u0947 10 \u092e\u093f\u0928\u091f, \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u0915\u0941\u091b \u092c\u093e\u0930\u0964 \u0915\u0948\u0902\u0938\u093f\u0932\u0947\u0936\u0928 \u0915\u093e\u092e \u0927\u094d\u092f\u093e\u0928-\u0924\u0902\u0924\u094d\u0930 \u0915\u0947 \u0932\u093f\u090f \u0925\u0915\u093e\u090a \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u090f\u0915 \u0932\u0902\u092c\u0947 \u0916\u0902\u0921 \u092e\u0947\u0902 \u0930\u0917\u0921\u093c\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u091c\u092c \u0938\u091f\u0940\u0915\u0924\u093e \u092c\u0939\u0915\u0928\u0947 \u0932\u0917\u0947 \u0924\u092d\u0940 \u0930\u0941\u0915 \u091c\u093e\u090f\u0901\u0964",research:"\u091c\u093f\u0938\u0915\u0940 \u0905\u092a\u0947\u0915\u094d\u0937\u093e \u0939\u0948, \u092a\u094d\u0930\u092e\u093e\u0923 \u0920\u0940\u0915 \u0909\u0938\u0940 \u0915\u0947 \u0932\u093f\u090f \u0938\u092c\u0938\u0947 \u092e\u091c\u093c\u092c\u0942\u0924 \u0939\u0948\u0902: \u0905\u092d\u094d\u092f\u093e\u0938 \u0938\u0947 \u0906\u092a \u0926\u0943\u0936\u094d\u092f \u0916\u094b\u091c \u0914\u0930 \u0915\u0948\u0902\u0938\u093f\u0932\u0947\u0936\u0928 \u0915\u093e\u0930\u094d\u092f\u094b\u0902 \u092e\u0947\u0902 \u0939\u0940 \u0924\u0947\u091c\u093c \u0914\u0930 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0938\u091f\u0940\u0915 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902, \u092f\u0939\u0940 \u0935\u091c\u0939 \u0939\u0948 \u0915\u093f d2 \u0914\u0930 \u092e\u093f\u0932\u0924\u0947-\u091c\u0941\u0932\u0924\u0947 \u092a\u0930\u0940\u0915\u094d\u0937\u0923 \u0927\u094d\u092f\u093e\u0928 \u0914\u0930 \u090f\u0915\u093e\u0917\u094d\u0930\u0924\u093e \u0915\u0947 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0928\u0948\u0926\u093e\u0928\u093f\u0915 \u092e\u093e\u092a \u0939\u0948\u0902\u0964 \u092f\u0939 \u0926\u093e\u0935\u0947 \u0915\u093f \u0907\u0938 \u0924\u0930\u0939 \u0915\u0940 \u0921\u094d\u0930\u093f\u0932 \u0935\u094d\u092f\u093e\u092a\u0915 \u0932\u093e\u092d \u0926\u0947\u0924\u0940 \u0939\u0948, \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u092c\u0941\u0926\u094d\u0927\u093f \u092c\u0922\u093c\u093e\u0924\u0940 \u0939\u0948, \u092f\u093e \u0938\u0902\u091c\u094d\u091e\u093e\u0928\u093e\u0924\u094d\u092e\u0915 \u0917\u093f\u0930\u093e\u0935\u091f \u0930\u094b\u0915\u0924\u0940 \u0939\u0948, \u0915\u0939\u0940\u0902 \u0915\u092e\u091c\u093c\u094b\u0930 \u0939\u0948\u0902; \u0938\u0902\u091c\u094d\u091e\u093e\u0928\u093e\u0924\u094d\u092e\u0915 \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u092e\u0947\u0902 \u0910\u0938\u093e \u0926\u0942\u0930-\u0939\u0938\u094d\u0924\u093e\u0902\u0924\u0930\u0923 \u0926\u093f\u0916\u093e \u092a\u093e\u0928\u093e \u0915\u0941\u0916\u094d\u092f\u093e\u0924 \u0930\u0942\u092a \u0938\u0947 \u0915\u0920\u093f\u0928 \u0939\u0948 \u0914\u0930 \u091c\u093c\u094d\u092f\u093e\u0926\u093e\u0924\u0930 \u091f\u093f\u0915\u0924\u093e \u0928\u0939\u0940\u0902 \u2014 \u0907\u0938\u0932\u093f\u090f \u0907\u0928 \u092c\u0921\u093c\u0947 \u0935\u093e\u0926\u094b\u0902 \u0915\u094b \u0938\u093e\u0935\u0927\u093e\u0928\u0940 \u0938\u0947 \u0932\u0947\u0902\u0964",rec:"\u092a\u0939\u0932\u0947 \u0938\u093e\u092b\u093c \u0938\u091f\u0940\u0915\u0924\u093e \u0915\u093e \u092a\u0940\u091b\u093e \u0915\u0930\u0947\u0902 \u0914\u0930 \u0917\u0924\u093f \u0915\u094b \u092c\u093e\u0926 \u092e\u0947\u0902 \u0906\u0928\u0947 \u0926\u0947\u0902; \u0917\u0932\u0924 \u091f\u0948\u092a \u0938\u0947 \u092d\u0930\u0940 \u090f\u0915 \u0924\u0947\u091c\u093c \u0926\u094c\u0921\u093c \u0917\u0932\u0924 \u0906\u0926\u0924 \u0915\u094b \u0938\u093e\u0927\u0924\u0940 \u0939\u0948\u0964",faq:[["\u0924\u0947\u091c\u093c \u091c\u093e\u0928\u093e \u092c\u0947\u0939\u0924\u0930 \u0939\u0948 \u092f\u093e \u0938\u091f\u0940\u0915 \u0930\u0939\u0928\u093e?","\u092a\u0939\u0932\u0947 \u0938\u091f\u0940\u0915\u0924\u093e\u0964 \u091c\u094b \u0939\u0941\u0928\u0930 \u0938\u093e\u0927\u093e \u091c\u093e \u0930\u0939\u093e \u0939\u0948 \u0935\u0939 \u0939\u0948 \u092c\u093f\u0928\u093e \u0917\u0932\u0924\u0940 \u0915\u093f\u090f \u092d\u094d\u0930\u093e\u092e\u0915 \u091a\u093f\u0939\u094d\u0928\u094b\u0902 \u0915\u094b \u091b\u093e\u0928\u0928\u093e, \u0907\u0938\u0932\u093f\u090f \u090f\u0915 \u0927\u0940\u092e\u0940 \u0938\u093e\u092b\u093c \u0926\u094c\u0921\u093c \u0917\u0932\u0924 \u091f\u0948\u092a \u0938\u0947 \u092d\u0930\u0940 \u0924\u0947\u091c\u093c \u0926\u094c\u0921\u093c \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u0939\u0948\u0964 \u091c\u092c \u0906\u092a\u0915\u0940 \u0938\u091f\u0940\u0915\u0924\u093e \u092a\u0915\u094d\u0915\u0940 \u0939\u094b \u091c\u093e\u0924\u0940 \u0939\u0948 \u0924\u094b \u0917\u0924\u093f \u0905\u092a\u0928\u0947-\u0906\u092a \u092c\u0922\u093c\u0924\u0940 \u0939\u0948\u0964"],["\u0915\u094d\u092f\u093e \u0907\u0938\u0938\u0947 \u092e\u0948\u0902 \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0940 \u091c\u093c\u093f\u0902\u0926\u0917\u0940 \u092e\u0947\u0902 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u090f\u0915\u093e\u0917\u094d\u0930 \u0939\u094b \u091c\u093e\u090a\u0901\u0917\u093e?","\u092f\u0939 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0930\u0942\u092a \u0938\u0947 \u0906\u092a\u0915\u094b \u0926\u0943\u0936\u094d\u092f \u0916\u094b\u091c \u0914\u0930 \u0915\u0948\u0902\u0938\u093f\u0932\u0947\u0936\u0928 \u0915\u093e\u0930\u094d\u092f\u094b\u0902 \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u092c\u0928\u093e\u0924\u093e \u0939\u0948, \u0914\u0930 \u0915\u0908 \u0932\u094b\u0917\u094b\u0902 \u0915\u094b \u092c\u093f\u0928\u093e \u092d\u091f\u0915\u0947 \u0916\u0902\u0917\u093e\u0932\u0928\u0947 \u0935\u093e\u0932\u0940 \u0935\u0939 \u0915\u0947\u0902\u0926\u094d\u0930\u093f\u0924 \u0932\u092f \u0905\u092d\u094d\u092f\u093e\u0938 \u092e\u0947\u0902 \u0938\u0941\u0916\u0926 \u0932\u0917\u0924\u0940 \u0939\u0948\u0964 \u092a\u0930 \u0905\u0938\u0902\u092c\u0902\u0927\u093f\u0924 \u0915\u093e\u0930\u094d\u092f\u094b\u0902 \u0924\u0915 \u0935\u094d\u092f\u093e\u092a\u0915 \u0939\u0938\u094d\u0924\u093e\u0902\u0924\u0930\u0923 \u0905\u091a\u094d\u091b\u0940 \u0924\u0930\u0939 \u092a\u094d\u0930\u092e\u093e\u0923\u093f\u0924 \u0928\u0939\u0940\u0902 \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0907\u0938\u0947 \u0927\u094d\u092f\u093e\u0928 \u0915\u093e \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u0907\u0932\u093e\u091c \u092e\u093e\u0928\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u0932\u0915\u094d\u0937\u093f\u0924 \u0927\u094d\u092f\u093e\u0928-\u0905\u092d\u094d\u092f\u093e\u0938 \u0938\u092e\u091d\u0947\u0902\u0964"],["\u092f\u0939 \u0936\u0941\u0932\u094d\u0924\u0947 \u091f\u0947\u092c\u0932 \u0938\u0947 \u0915\u0948\u0938\u0947 \u0905\u0932\u0917 \u0939\u0948?","\u0936\u0941\u0932\u094d\u0924\u0947 \u091f\u0947\u092c\u0932 \u092e\u0947\u0902 \u0939\u0930 \u0915\u093f\u0938\u094d\u092e \u0915\u0940 \u090f\u0915 \u0939\u0940 \u091a\u0940\u091c\u093c \u0939\u094b\u0924\u0940 \u0939\u0948 \u0914\u0930 \u0906\u092a \u0909\u0928\u094d\u0939\u0947\u0902 \u090f\u0915 \u0924\u092f \u0915\u094d\u0930\u092e \u092e\u0947\u0902 \u0922\u0942\u0901\u0922\u0924\u0947 \u0939\u0948\u0902, \u091c\u094b \u090f\u0915 \u091f\u093f\u0915\u0940 \u0928\u091c\u093c\u0930 \u0915\u0947 \u0907\u0930\u094d\u0926-\u0917\u093f\u0930\u094d\u0926 \u0926\u0943\u0937\u094d\u091f\u093f-\u092a\u0930\u093f\u0927\u093f \u0915\u094b \u0938\u093e\u0927\u0924\u093e \u0939\u0948\u0964 \u092f\u0939\u093e\u0901 \u092c\u0939\u0941\u0924-\u0938\u0940 \u091a\u0940\u091c\u093c\u0947\u0902 \u090f\u0915 \u091c\u0948\u0938\u0940 \u0926\u093f\u0916\u0924\u0940 \u0939\u0948\u0902 \u0914\u0930 \u0906\u092a\u0915\u094b \u0939\u0930 \u090f\u0915 \u0915\u094b \u090f\u0915 \u0928\u093f\u092f\u092e \u092a\u0930 \u092a\u0930\u0916\u0928\u093e \u0939\u094b\u0924\u093e \u0939\u0948, \u091c\u094b \u092d\u094d\u0930\u093e\u092e\u0915 \u091a\u093f\u0939\u094d\u0928\u094b\u0902 \u0915\u094b \u091b\u093e\u0928\u0928\u0947 \u0914\u0930 \u092e\u093f\u0932\u0924\u0947-\u091c\u0941\u0932\u0924\u0947 \u091a\u093f\u0939\u094d\u0928\u094b\u0902 \u092a\u0930 \u091f\u0948\u092a \u0915\u0930\u0928\u0947 \u0915\u0940 \u0932\u0932\u0915 \u0930\u094b\u0915\u0928\u0947 \u092a\u0930 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u091f\u093f\u0915\u093e \u0939\u0948\u0964"]],variants:"\u0935\u093f\u0935\u093f\u0927\u0924\u093e\u090f\u0901 \u0932\u0915\u094d\u0937\u094d\u092f-\u0928\u093f\u092f\u092e \u092c\u0926\u0932\u0924\u0940 \u0939\u0948\u0902 (\u090f\u0915 \u0905\u0915\u094d\u0937\u0930, \u0905\u0915\u094d\u0937\u0930\u094b\u0902 \u0915\u093e \u091c\u094b\u0921\u093c\u093e, \u0915\u094b\u0908 \u0906\u0915\u0943\u0924\u093f \u092f\u093e \u0930\u0902\u0917, \u092f\u093e \u0915\u094b\u0908 \u091a\u093f\u0939\u094d\u0928 \u0924\u092d\u0940 \u091c\u092c \u0909\u0938 \u092a\u0930 \u0915\u094b\u0908 \u0916\u093c\u093e\u0938 \u0928\u093f\u0936\u093e\u0928 \u0939\u094b), \u092e\u0948\u0926\u093e\u0928 \u0915\u093e \u0918\u0928\u093e\u092a\u0928 \u0914\u0930 \u0906\u0915\u093e\u0930, \u0918\u0921\u093c\u0940 \u0924\u092f \u0939\u094b \u092f\u093e \u0906\u092a\u0915\u0940 \u0905\u092a\u0928\u0940 \u0930\u092b\u093c\u094d\u0924\u093e\u0930 \u092a\u0930, \u0914\u0930 \u092d\u094d\u0930\u093e\u092e\u0915 \u091a\u093f\u0939\u094d\u0928 \u0932\u0915\u094d\u0937\u094d\u092f \u0938\u0947 \u0915\u092e \u092f\u093e \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u092e\u093f\u0932\u0924\u0947-\u091c\u0941\u0932\u0924\u0947 \u0939\u094b\u0902 \u0924\u093e\u0915\u093f \u0916\u094b\u091c \u0915\u0920\u093f\u0928 \u0939\u094b\u0964"},zh:{about:"\u300a\u6821\u5bf9\uff1a\u4e13\u6ce8\u300b\u662f\u4e00\u9879\u5212\u6d88\u4efb\u52a1\uff1a\u5c4f\u5e55\u4e0a\u94fa\u6ee1\u4e86\u4e00\u5927\u7247\u5916\u5f62\u76f8\u4f3c\u7684\u5b57\u7b26\uff0c\u4f60\u7684\u4efb\u52a1\u662f\u9010\u884c\u626b\u89c6\uff0c\u53ea\u70b9\u6309\u7b26\u5408\u7ed9\u5b9a\u89c4\u5219\u7684\u76ee\u6807\uff0c\u540c\u65f6\u65e0\u89c6\u5176\u4f59\u7684\u4e00\u5207\u3002\u5b83\u662f\u6821\u5bf9\u5458\u641c\u5bfb\u67d0\u4e2a\u7279\u5b9a\u5b57\u6bcd\u7684\u6570\u5b57\u7248\u2014\u2014\u5728\u4e0d\u6f0f\u70b9\u3001\u4e0d\u70b9\u9519\u7684\u524d\u63d0\u4e0b\u5c3d\u91cf\u5feb\u5730\u5b8c\u6210\u3002",benefit:"\u5b83\u8bad\u7ec3\u9009\u62e9\u6027\u6ce8\u610f\u548c\u6301\u7eed\u6027\u6ce8\u610f\u3001\u89c6\u89c9\u626b\u89c6\u901f\u5ea6\uff0c\u4ee5\u53ca\u5728\u65f6\u95f4\u538b\u529b\u4e0b\u7684\u4e13\u6ce8\u529b\uff0c\u8fd8\u6709\u90a3\u79cd\u6301\u7eed\u8df3\u8fc7\u8fd1\u4f3c\u5e72\u6270\u9879\u3001\u5fcd\u4f4f\u4e0d\u53bb\u70b9\u5b83\u4eec\u7684\u51b2\u52a8\u63a7\u5236\u80fd\u529b\u3002",history:"\u5212\u6d88\u4efb\u52a1\u662f\u6ce8\u610f\u529b\u7814\u7a76\u4e2d\u6700\u53e4\u8001\u7684\u5de5\u5177\u4e4b\u4e00\u3002\u6cd5\u56fd\u5fc3\u7406\u5b66\u5bb6\u672c\u6770\u660e\xb7\u5e03\u5c14\u4e1c\uff08Benjamin Bourdon\uff09\u5728 19 \u4e16\u7eaa 90 \u5e74\u4ee3\u7528\u5b57\u6bcd\u5212\u6d88\u6765\u7814\u7a76\u89c6\u89c9\u8fa8\u522b\uff0c\u56fe\u5362\u5179\uff08Toulouse\uff09\u548c\u76ae\u57c3\u9f99\uff08Pi\xe9ron\uff09\u4e8e 1904 \u5e74\u53d1\u8868\u4e86\u4ed6\u4eec\u7684\u7248\u672c\uff0c\u8fd9\u4e00\u5f62\u5f0f\u540e\u6765\u5728\u4e34\u5e8a\u795e\u7ecf\u5fc3\u7406\u5b66\u4e2d\u4f5c\u4e3a\u4e00\u79cd\u5feb\u901f\u7684\u7eb8\u7b14\u6d4b\u91cf\u624b\u6bb5\u6d41\u4f20\u5f00\u6765\uff0c\u7528\u4ee5\u8bc4\u4f30\u6ce8\u610f\u529b\u3001\u626b\u89c6\u548c\u89c6\u89c9\u5ffd\u7565\u3002",creator:"\u5b83\u6ca1\u6709\u5355\u4e00\u7684\u53d1\u660e\u8005\uff1b\u8fd9\u9879\u7ec3\u4e60\u6e90\u81ea\u7531\u5e03\u5c14\u4e1c\uff0819 \u4e16\u7eaa 90 \u5e74\u4ee3\uff09\u548c\u56fe\u5362\u5179-\u76ae\u57c3\u9f99\uff081904 \u5e74\uff09\u5f00\u521b\u7684\u5212\u6d88\u4efb\u52a1\u4f20\u7edf\u3002\u5176\u6700\u8457\u540d\u7684\u73b0\u4ee3\u540e\u88d4\u662f d2 \u6ce8\u610f\u529b\u6d4b\u9a8c\uff0c\u7531\u5fb7\u56fd\u5fc3\u7406\u5b66\u5bb6\u7f57\u5c14\u592b\xb7\u5e03\u91cc\u80af\u574e\u666e\uff08Rolf Brickenkamp\uff09\u521b\u5236\u3001\u4e8e 1962 \u5e74\u9996\u6b21\u53d1\u8868\uff08\u540e\u4fee\u8ba2\u4e3a d2-R\uff09\uff0c\u8fd9\u7c7b\u6e38\u620f\u4e0e\u4e4b\u6700\u4e3a\u76f8\u4f3c\u3002",methods:"\u6309\u56fa\u5b9a\u7684\u9605\u8bfb\u6a21\u5f0f\u626b\u89c6\u2014\u2014\u4ece\u5de6\u5230\u53f3\u3001\u4ece\u4e0a\u5230\u4e0b\uff0c\u800c\u4e0d\u662f\u5728\u5b57\u7b26\u7247\u91cc\u968f\u610f\u8df3\u8dc3\u3002\u5f00\u59cb\u524d\u5148\u628a\u76ee\u6807\u89c4\u5219\u7262\u8bb0\u4e8e\u5fc3\uff0c\u514d\u5f97\u884c\u5230\u4e00\u534a\u8fd8\u8981\u56de\u5934\u91cd\u8bfb\uff1b\u529b\u6c42\u4fdd\u6301\u7a33\u5b9a\u7684\u8282\u594f\uff0c\u8ba9\u51c6\u786e\u7387\u4f18\u5148\u3001\u901f\u5ea6\u5728\u6b64\u4e4b\u4e0a\u7d2f\u79ef\u3002\u5f53\u4f60\u5bdf\u89c9\u81ea\u5df1\u53d8\u6162\u6216\u5f00\u59cb\u6f0f\u70b9\u65f6\uff0c\u90a3\u4e2a\u75b2\u52b3\u4e34\u754c\u70b9\u6070\u6070\u662f\u503c\u5f97\u7a0d\u7a0d\u903c\u4e00\u903c\u81ea\u5df1\u7684\u8fb9\u754c\u3002",duration:"\u77ed\u800c\u9891\u7e41\u7684\u7ec3\u4e60\u6700\u6709\u6548\uff1a\u5927\u7ea6\u6bcf\u5929 5 \u5230 10 \u5206\u949f\uff0c\u6bcf\u5468\u51e0\u6b21\u3002\u5212\u6d88\u5bf9\u6ce8\u610f\u529b\u7cfb\u7edf\u6765\u8bf4\u5f88\u8d39\u795e\uff0c\u6240\u4ee5\u5f53\u51c6\u786e\u7387\u5f00\u59cb\u6f02\u79fb\u65f6\u5c31\u505c\u4e0b\uff0c\u800c\u4e0d\u662f\u786c\u6491\u7740\u71ac\u5b8c\u4e00\u5927\u6bb5\u3002",research:"\u8bc1\u636e\u6700\u5145\u5206\u7684\u6070\u6070\u662f\u4f60\u80fd\u9884\u6599\u5230\u7684\u90e8\u5206\uff1a\u7ecf\u8fc7\u7ec3\u4e60\uff0c\u4f60\u5728\u89c6\u89c9\u641c\u7d22\u548c\u5212\u6d88\u4efb\u52a1\u672c\u8eab\u4e0a\u4f1a\u53d8\u5f97\u66f4\u5feb\u3001\u66f4\u51c6\uff0c\u8fd9\u6b63\u662f d2 \u53ca\u7c7b\u4f3c\u6d4b\u9a8c\u88ab\u89c6\u4e3a\u53ef\u4fe1\u7684\u4e34\u5e8a\u6ce8\u610f\u529b\u4e0e\u4e13\u6ce8\u529b\u6d4b\u91cf\u624b\u6bb5\u7684\u539f\u56e0\u3002\u81f3\u4e8e\u8fd9\u7c7b\u7ec3\u4e60\u80fd\u5e26\u6765\u5e7f\u6cdb\u6536\u76ca\u3001\u63d0\u5347\u6574\u4f53\u667a\u529b\u6216\u9884\u9632\u8ba4\u77e5\u8870\u9000\u7684\u8bf4\u6cd5\u5219\u8981\u8584\u5f31\u5f97\u591a\uff1b\u5728\u8ba4\u77e5\u8bad\u7ec3\u4e2d\uff0c\u8fd9\u79cd\u8fdc\u8fc1\u79fb\u662f\u51fa\u4e86\u540d\u5730\u96be\u4ee5\u8bc1\u5b9e\u3001\u4e14\u591a\u534a\u7ecf\u4e0d\u8d77\u68c0\u9a8c\uff0c\u6240\u4ee5\u5bf9\u90a3\u4e9b\u5b8f\u5927\u627f\u8bfa\u8981\u4fdd\u6301\u8c28\u614e\u3002",rec:"\u5148\u8ffd\u6c42\u5e72\u51c0\u7684\u51c6\u786e\u7387\uff0c\u8ba9\u901f\u5ea6\u968f\u4e4b\u800c\u6765\uff1b\u4e00\u904d\u70b9\u9519\u8fde\u8fde\u7684\u5feb\u901f\u64cd\u4f5c\uff0c\u8bad\u7ec3\u7684\u53ea\u662f\u574f\u4e60\u60ef\u3002",faq:[["\u662f\u5e94\u8be5\u6c42\u5feb\uff0c\u8fd8\u662f\u6c42\u51c6\uff1f","\u51c6\u786e\u4f18\u5148\u3002\u8fd9\u91cc\u8bad\u7ec3\u7684\u6280\u80fd\u662f\u65e0\u5dee\u9519\u5730\u6ee4\u9664\u5e72\u6270\u9879\uff0c\u6240\u4ee5\u4e00\u904d\u6162\u800c\u5e72\u51c0\u80dc\u8fc7\u4e00\u904d\u5feb\u800c\u70b9\u9519\u8fde\u8fde\u3002\u4e00\u65e6\u51c6\u786e\u7387\u624e\u5b9e\u4e86\uff0c\u901f\u5ea6\u81ea\u7136\u4f1a\u6da8\u4e0a\u6765\u3002"],["\u8fd9\u4f1a\u8ba9\u6211\u5728\u65e5\u5e38\u751f\u6d3b\u4e2d\u66f4\u4e13\u6ce8\u5417\uff1f","\u5b83\u786e\u5b9e\u80fd\u53ef\u9760\u5730\u63d0\u5347\u4f60\u5728\u89c6\u89c9\u641c\u7d22\u548c\u5212\u6d88\u4efb\u52a1\u4e0a\u7684\u8868\u73b0\uff0c\u8bb8\u591a\u4eba\u4e5f\u89c9\u5f97\u8fd9\u79cd\u4e13\u6ce8\u3001\u626b\u89c6\u800c\u4e0d\u8d70\u795e\u7684\u8282\u594f\u7ec3\u8d77\u6765\u5f88\u8212\u670d\u3002\u4f46\u5411\u65e0\u5173\u4efb\u52a1\u7684\u5e7f\u6cdb\u8fc1\u79fb\u5e76\u6ca1\u6709\u5f97\u5230\u5145\u5206\u8bc1\u5b9e\uff0c\u6240\u4ee5\u8bf7\u628a\u5b83\u5f53\u4f5c\u6709\u9488\u5bf9\u6027\u7684\u6ce8\u610f\u529b\u7ec3\u4e60\uff0c\u800c\u975e\u4e00\u5242\u901a\u7528\u7684\u4e13\u6ce8\u826f\u65b9\u3002"],["\u8fd9\u548c\u8212\u5c14\u7279\u8868\u6709\u4ec0\u4e48\u4e0d\u540c\uff1f","\u8212\u5c14\u7279\u8868\u6bcf\u79cd\u6761\u76ee\u53ea\u6709\u4e00\u4e2a\uff0c\u4f60\u6309\u8bbe\u5b9a\u987a\u5e8f\u53bb\u627e\u5b83\u4eec\uff0c\u8bad\u7ec3\u7684\u662f\u56fa\u5b9a\u89c6\u7ebf\u5468\u56f4\u7684\u89c6\u91ce\u3002\u800c\u5728\u8fd9\u91cc\uff0c\u8bb8\u591a\u6761\u76ee\u957f\u5f97\u5f88\u50cf\uff0c\u4f60\u5fc5\u987b\u9010\u4e00\u5bf9\u7167\u89c4\u5219\u53bb\u5224\u65ad\uff0c\u8fd9\u66f4\u504f\u5411\u4e8e\u6ee4\u9664\u5e72\u6270\u9879\u3001\u62b5\u6297\u53bb\u70b9\u8fd1\u4f3c\u9879\u7684\u51b2\u52a8\u3002"]],variants:"\u5404\u79cd\u53d8\u4f53\u4f1a\u6539\u53d8\u76ee\u6807\u89c4\u5219\uff08\u5355\u4e2a\u5b57\u6bcd\u3001\u4e00\u5bf9\u5b57\u6bcd\u3001\u67d0\u79cd\u5f62\u72b6\u6216\u989c\u8272\uff0c\u6216\u4ec5\u5f53\u5b57\u7b26\u5e26\u6709\u7279\u5b9a\u6807\u8bb0\u65f6\u624d\u7b97\uff09\uff0c\u6539\u53d8\u5b57\u7b26\u7247\u7684\u5bc6\u5ea6\u548c\u5927\u5c0f\uff0c\u6539\u53d8\u8ba1\u65f6\u662f\u56fa\u5b9a\u8fd8\u662f\u81ea\u5b9a\u6b65\u8c03\uff0c\u4ee5\u53ca\u8ba9\u5e72\u6270\u9879\u4e0e\u76ee\u6807\u66f4\u50cf\u6216\u66f4\u4e0d\u50cf\uff0c\u4ece\u800c\u52a0\u5927\u641c\u7d22\u96be\u5ea6\u3002"}},"reading-span":{ru:{about:"\u0412 \xabReading Span\xbb \u0432\u0430\u043c \u043f\u043e\u043a\u0430\u0437\u044b\u0432\u0430\u044e\u0442 \u043a\u043e\u0440\u043e\u0442\u043a\u043e\u0435 \u043f\u0440\u0435\u0434\u043b\u043e\u0436\u0435\u043d\u0438\u0435, \u043a\u043e\u0442\u043e\u0440\u043e\u0435 \u043d\u0443\u0436\u043d\u043e \u043f\u0440\u043e\u0447\u0438\u0442\u0430\u0442\u044c (\u0430 \u0447\u0430\u0441\u0442\u043e \u0438 \u043e\u0446\u0435\u043d\u0438\u0442\u044c, \u043e\u0441\u043c\u044b\u0441\u043b\u0435\u043d\u043d\u043e\u0435 \u043e\u043d\u043e \u0438\u043b\u0438 \u043d\u0435\u0442), \u0430 \u0437\u0430\u0442\u0435\u043c \u043e\u0434\u043d\u043e \u0441\u043b\u043e\u0432\u043e, \u043a\u043e\u0442\u043e\u0440\u043e\u0435 \u043d\u0430\u0434\u043e \u0443\u0434\u0435\u0440\u0436\u0430\u0442\u044c \u0432 \u043f\u0430\u043c\u044f\u0442\u0438. \u041f\u043e\u0441\u043b\u0435 \u0441\u0435\u0440\u0438\u0438 \u0438\u0437 \u0434\u0432\u0443\u0445, \u0442\u0440\u0451\u0445 \u0438 \u0431\u043e\u043b\u0435\u0435 \u043f\u0440\u0435\u0434\u043b\u043e\u0436\u0435\u043d\u0438\u0439 \u0432\u044b \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0438\u0442\u0435 \u044d\u0442\u0438 \u0441\u043b\u043e\u0432\u0430 \u0432 \u0442\u043e\u043c \u043f\u043e\u0440\u044f\u0434\u043a\u0435, \u0432 \u043a\u0430\u043a\u043e\u043c \u043e\u043d\u0438 \u0448\u043b\u0438. \u0412\u0441\u044f \u0441\u043e\u043b\u044c \u0432 \u043e\u0434\u043d\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u043e\u0441\u0442\u0438: \u0432\u044b \u043e\u0431\u0440\u0430\u0431\u0430\u0442\u044b\u0432\u0430\u0435\u0442\u0435 \u043a\u0430\u0436\u0434\u043e\u0435 \u043f\u0440\u0435\u0434\u043b\u043e\u0436\u0435\u043d\u0438\u0435, \u043f\u043e\u043a\u0430 \u0440\u0430\u043d\u0435\u0435 \u043f\u043e\u043a\u0430\u0437\u0430\u043d\u043d\u044b\u0435 \u0441\u043b\u043e\u0432\u0430 \u0434\u0435\u0440\u0436\u0430\u0442\u0441\u044f \u0432 \u043f\u0430\u043c\u044f\u0442\u0438, \u0438 \u0434\u043b\u0438\u043d\u0430 \u0441\u0435\u0440\u0438\u0438 \u043f\u043e\u0441\u0442\u0435\u043f\u0435\u043d\u043d\u043e \u0440\u0430\u0441\u0442\u0451\u0442.",benefit:"\u0423\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u0435 \u043d\u0430\u0433\u0440\u0443\u0436\u0430\u0435\u0442 \u0440\u0430\u0431\u043e\u0447\u0443\u044e \u043f\u0430\u043c\u044f\u0442\u044c, \u0430 \u0442\u043e\u0447\u043d\u0435\u0435 \u0441\u043f\u043e\u0441\u043e\u0431\u043d\u043e\u0441\u0442\u044c \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0442\u044c \u0438\u043d\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u044e, \u043e\u0434\u043d\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u043e \u0437\u0430\u043d\u0438\u043c\u0430\u044f \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u0447\u0435\u043c-\u0442\u043e \u0435\u0449\u0451. \u0418\u043c\u0435\u043d\u043d\u043e \u044d\u0442\u0430 \u0434\u0432\u043e\u0439\u043d\u0430\u044f \u043d\u0430\u0433\u0440\u0443\u0437\u043a\u0430, \u0445\u0440\u0430\u043d\u0435\u043d\u0438\u0435 \u043f\u043b\u044e\u0441 \u043e\u0431\u0440\u0430\u0431\u043e\u0442\u043a\u0430, \u043e\u0442\u043b\u0438\u0447\u0430\u0435\u0442 \u0437\u0430\u0434\u0430\u0447\u0443 \u043e\u0442 \u043f\u0440\u043e\u0441\u0442\u043e\u0433\u043e \u0441\u043f\u0438\u0441\u043a\u0430 \u0441\u043b\u043e\u0432 \u0438 \u0442\u0435\u0441\u043d\u043e \u0441\u0432\u044f\u0437\u0430\u043d\u0430 \u0441 \u043f\u043e\u043d\u0438\u043c\u0430\u043d\u0438\u0435\u043c \u0442\u0435\u043a\u0441\u0442\u0430.",history:"\u0412\u0441\u0451 \u043d\u0430\u0447\u0430\u043b\u043e\u0441\u044c \u043a\u0430\u043a \u043b\u0430\u0431\u043e\u0440\u0430\u0442\u043e\u0440\u043d\u0430\u044f \u043c\u0435\u0442\u043e\u0434\u0438\u043a\u0430 \u0438\u0437\u043c\u0435\u0440\u0435\u043d\u0438\u044f \u0440\u0430\u0431\u043e\u0447\u0435\u0439 \u043f\u0430\u043c\u044f\u0442\u0438, \u0430 \u043d\u0435 \u043a\u0430\u043a \u0438\u0433\u0440\u0430. \u041f\u043e\u0441\u043b\u0435 \u0442\u043e\u0433\u043e \u043a\u0430\u043a \u0414\u0430\u043d\u0435\u043c\u0430\u043d \u0438 \u041a\u0430\u0440\u043f\u0435\u043d\u0442\u0435\u0440 \u043e\u043f\u0438\u0441\u0430\u043b\u0438 \u0435\u0451 \u0432 1980 \u0433\u043e\u0434\u0443, \u0438\u0434\u0435\u044f \u0431\u044b\u0441\u0442\u0440\u043e \u0440\u0430\u0437\u043e\u0448\u043b\u0430\u0441\u044c: \u0422\u0451\u0440\u043d\u0435\u0440 \u0438 \u042d\u043d\u0433\u043b \u0432 1989-\u043c \u043f\u043e\u043a\u0430\u0437\u0430\u043b\u0438, \u0447\u0442\u043e \u0447\u0442\u0435\u043d\u0438\u0435 \u043f\u0440\u0435\u0434\u043b\u043e\u0436\u0435\u043d\u0438\u0439 \u043c\u043e\u0436\u043d\u043e \u0437\u0430\u043c\u0435\u043d\u0438\u0442\u044c \u0430\u0440\u0438\u0444\u043c\u0435\u0442\u0438\u043a\u043e\u0439 (\u0442\u0430\u043a \u043f\u043e\u044f\u0432\u0438\u043b\u0441\u044f operation span), \u0430 \u0441\u043b\u0435\u0434\u043e\u043c \u0432\u043e\u0437\u043d\u0438\u043a\u043b\u043e \u0446\u0435\u043b\u043e\u0435 \u0441\u0435\u043c\u0435\u0439\u0441\u0442\u0432\u043e \u043a\u043e\u043c\u043f\u044c\u044e\u0442\u0435\u0440\u043d\u044b\u0445 \u0437\u0430\u0434\u0430\u0447 \u043d\u0430 \u043a\u043e\u043c\u043f\u043b\u0435\u043a\u0441\u043d\u044b\u0439 \u043e\u0431\u044a\u0451\u043c, \u0441\u0442\u0430\u0432\u0448\u0438\u0445 \u0441\u0442\u0430\u043d\u0434\u0430\u0440\u0442\u043d\u044b\u043c \u0438\u043d\u0441\u0442\u0440\u0443\u043c\u0435\u043d\u0442\u043e\u043c \u043a\u043e\u0433\u043d\u0438\u0442\u0438\u0432\u043d\u043e\u0439 \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u0438.",creator:"\u041c\u0435\u0442\u043e\u0434\u0438\u043a\u0443 \u0441\u043e\u0437\u0434\u0430\u043b\u0438 \u041c\u0435\u0440\u0435\u0434\u0438\u0442 \u0414\u0430\u043d\u0435\u043c\u0430\u043d \u0438 \u041f\u0430\u0442\u0440\u0438\u0446\u0438\u044f \u041a\u0430\u0440\u043f\u0435\u043d\u0442\u0435\u0440 \u0432 1980 \u0433\u043e\u0434\u0443 \u0432 \u0441\u0442\u0430\u0442\u044c\u0435 \u0432 \u0436\u0443\u0440\u043d\u0430\u043b\u0435 Journal of Verbal Learning and Verbal Behavior. \u0415\u0451 \u043f\u0440\u0438\u043d\u044f\u0442\u043e \u0441\u0447\u0438\u0442\u0430\u0442\u044c \u043f\u0435\u0440\u0432\u043e\u0439 \u0437\u0430\u0434\u0430\u0447\u0435\u0439 \u043d\u0430 \u043a\u043e\u043c\u043f\u043b\u0435\u043a\u0441\u043d\u044b\u0439 \u043e\u0431\u044a\u0451\u043c \u043f\u0430\u043c\u044f\u0442\u0438, \u043d\u0430\u0440\u044f\u0434\u0443 \u0441 \u0438\u0445 \u0436\u0435 \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u043e\u043c \u043d\u0430 \u0441\u043b\u0443\u0445 (listening span).",methods:"\u0427\u0438\u0442\u0430\u0439\u0442\u0435 \u0438\u043b\u0438 \u043e\u0446\u0435\u043d\u0438\u0432\u0430\u0439\u0442\u0435 \u043a\u0430\u0436\u0434\u043e\u0435 \u043f\u0440\u0435\u0434\u043b\u043e\u0436\u0435\u043d\u0438\u0435 \u0432 \u043d\u043e\u0440\u043c\u0430\u043b\u044c\u043d\u043e\u043c, \u0447\u0435\u0441\u0442\u043d\u043e\u043c \u0442\u0435\u043c\u043f\u0435, \u0430 \u043d\u0435 \u043f\u0440\u043e\u0441\u043a\u0430\u043a\u0438\u0432\u0430\u0439\u0442\u0435 \u043e\u0431\u0440\u0430\u0431\u043e\u0442\u043a\u0443 \u0440\u0430\u0434\u0438 \u0441\u043e\u0445\u0440\u0430\u043d\u0435\u043d\u0438\u044f \u0441\u043b\u043e\u0432: \u0432\u0441\u044f \u0442\u0440\u0443\u0434\u043d\u043e\u0441\u0442\u044c \u0438\u043c\u0435\u043d\u043d\u043e \u0432 \u0442\u043e\u043c, \u0447\u0442\u043e\u0431\u044b \u0434\u0435\u043b\u0430\u0442\u044c \u0438 \u0442\u043e, \u0438 \u0434\u0440\u0443\u0433\u043e\u0435 \u0441\u0440\u0430\u0437\u0443. \u041d\u0435 \u0437\u0443\u0431\u0440\u0438\u0442\u0435 \u0441\u043b\u043e\u0432\u0430 \u043f\u043e \u043a\u0440\u0443\u0433\u0443, \u0430 \u043f\u0440\u0438\u0432\u044f\u0437\u044b\u0432\u0430\u0439\u0442\u0435 \u043a\u0430\u0436\u0434\u043e\u0435 \u043a \u0441\u0432\u043e\u0435\u043c\u0443 \u043f\u0440\u0435\u0434\u043b\u043e\u0436\u0435\u043d\u0438\u044e \u0438\u043b\u0438 \u0441\u0432\u044f\u0437\u044b\u0432\u0430\u0439\u0442\u0435 \u0438\u0445 \u0431\u044b\u0441\u0442\u0440\u044b\u043c \u043e\u0431\u0440\u0430\u0437\u043e\u043c \u043b\u0438\u0431\u043e \u043c\u0438\u043d\u0438-\u0438\u0441\u0442\u043e\u0440\u0438\u0435\u0439. \u0423\u0432\u0435\u043b\u0438\u0447\u0438\u0432\u0430\u0439\u0442\u0435 \u0434\u043b\u0438\u043d\u0443 \u0441\u0435\u0440\u0438\u0438 \u0442\u043e\u043b\u044c\u043a\u043e \u0442\u043e\u0433\u0434\u0430, \u043a\u043e\u0433\u0434\u0430 \u0443\u0432\u0435\u0440\u0435\u043d\u043d\u043e \u0434\u0435\u0440\u0436\u0438\u0442\u0435 \u0442\u0435\u043a\u0443\u0449\u0443\u044e.",duration:"\u041b\u0443\u0447\u0448\u0435 \u0432\u0441\u0435\u0433\u043e \u0440\u0430\u0431\u043e\u0442\u0430\u044e\u0442 \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u0435 \u0441\u043e\u0441\u0440\u0435\u0434\u043e\u0442\u043e\u0447\u0435\u043d\u043d\u044b\u0435 \u043f\u043e\u0434\u0445\u043e\u0434\u044b: \u043f\u0440\u0438\u043c\u0435\u0440\u043d\u043e 10-15 \u043c\u0438\u043d\u0443\u0442 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0440\u0430\u0437 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e. \u0423\u0442\u043e\u043c\u043b\u0435\u043d\u0438\u0435 \u0437\u0434\u0435\u0441\u044c \u043d\u0430\u0441\u0442\u0443\u043f\u0430\u0435\u0442 \u0431\u044b\u0441\u0442\u0440\u043e, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u043e\u0441\u0442\u0430\u043d\u0430\u0432\u043b\u0438\u0432\u0430\u0439\u0442\u0435\u0441\u044c, \u043a\u043e\u0433\u0434\u0430 \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u044c \u043d\u0430\u0447\u0438\u043d\u0430\u0435\u0442 \u043f\u0430\u0434\u0430\u0442\u044c, \u0430 \u043d\u0435 \u043f\u0440\u043e\u0434\u0430\u0432\u043b\u0438\u0432\u0430\u0439\u0442\u0435 \u0437\u0430\u043d\u044f\u0442\u0438\u0435 \u043d\u0430 \u0443\u0441\u0442\u0430\u043b\u043e\u0441\u0442\u0438.",research:"\u0414\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432\u0430 \u0441\u0438\u043b\u044c\u043d\u0435\u0435 \u0432\u0441\u0435\u0433\u043e \u0440\u043e\u0432\u043d\u043e \u0442\u0430\u043c, \u0433\u0434\u0435 \u044d\u0442\u043e\u0433\u043e \u0438 \u0436\u0434\u0451\u0448\u044c: reading span \u044d\u0442\u043e \u043d\u0430\u0434\u0451\u0436\u043d\u0430\u044f, \u0445\u043e\u0440\u043e\u0448\u043e \u043f\u0440\u043e\u0432\u0435\u0440\u0435\u043d\u043d\u0430\u044f \u043c\u0435\u0440\u0430 \u043e\u0431\u044a\u0451\u043c\u0430 \u0440\u0430\u0431\u043e\u0447\u0435\u0439 \u043f\u0430\u043c\u044f\u0442\u0438, \u0438 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442\u044b \u043a\u043e\u0440\u0440\u0435\u043b\u0438\u0440\u0443\u044e\u0442 \u0441 \u043f\u043e\u043d\u0438\u043c\u0430\u043d\u0438\u0435\u043c \u043f\u0440\u043e\u0447\u0438\u0442\u0430\u043d\u043d\u043e\u0433\u043e. \u0410 \u0432\u043e\u0442 \u043f\u043e\u0443\u043c\u043d\u0435\u0442\u044c \u0432 \u0446\u0435\u043b\u043e\u043c \u043e\u043d\u0430 \u043d\u0430\u0434\u0451\u0436\u043d\u043e \u043d\u0435 \u043f\u043e\u043c\u043e\u0433\u0430\u0435\u0442. \u041a\u0440\u0443\u043f\u043d\u044b\u0435 \u043c\u0435\u0442\u0430\u0430\u043d\u0430\u043b\u0438\u0437\u044b \u0438 \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u0438\u0440\u0443\u0435\u043c\u044b\u0435 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u044f \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0438 \u0440\u0430\u0431\u043e\u0447\u0435\u0439 \u043f\u0430\u043c\u044f\u0442\u0438 (\u041c\u0435\u043b\u0431\u0438-\u041b\u0435\u0440\u0432\u043e\u0433 \u0441 \u043a\u043e\u043b\u043b\u0435\u0433\u0430\u043c\u0438, \u0420\u0435\u0434\u0438\u043a \u0441 \u043a\u043e\u043b\u043b\u0435\u0433\u0430\u043c\u0438) \u043f\u043e\u043a\u0430\u0437\u0430\u043b\u0438, \u0447\u0442\u043e \u043f\u0440\u0438\u0440\u043e\u0441\u0442 \u0434\u0435\u0440\u0436\u0438\u0442\u0441\u044f \u0431\u043b\u0438\u0437\u043a\u043e \u043a \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u043c\u043e\u0439 \u0437\u0430\u0434\u0430\u0447\u0435 \u0438 \u043d\u0435 \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0438\u0442\u0441\u044f \u043d\u0430 \u043f\u043e\u0434\u0432\u0438\u0436\u043d\u044b\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0438\u043b\u0438 \u043f\u043e\u0432\u0441\u0435\u0434\u043d\u0435\u0432\u043d\u043e\u0435 \u043c\u044b\u0448\u043b\u0435\u043d\u0438\u0435, \u0442\u0430\u043a \u0447\u0442\u043e \u043a \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f\u043c \xab\u043f\u043b\u044e\u0441 IQ\xbb \u0441\u0442\u043e\u0438\u0442 \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u044c\u0441\u044f \u0441 \u043e\u0441\u0442\u043e\u0440\u043e\u0436\u043d\u043e\u0441\u0442\u044c\u044e.",rec:"\u0418\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0439\u0442\u0435 \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u0435, \u0447\u0442\u043e\u0431\u044b \u0447\u0435\u0441\u0442\u043d\u043e \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u0438 \u043e\u0446\u0435\u043d\u0438\u0432\u0430\u0442\u044c \u0440\u0430\u0431\u043e\u0447\u0443\u044e \u043f\u0430\u043c\u044f\u0442\u044c, \u0430 \u043d\u0435 \u043a\u0430\u043a \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u0439 \u043f\u0443\u0442\u044c \u043a \u0432\u044b\u0441\u043e\u043a\u043e\u043c\u0443 IQ, \u0438 \u043d\u0435 \u0445\u0430\u043b\u0442\u0443\u0440\u044c\u0442\u0435 \u0441 \u0447\u0442\u0435\u043d\u0438\u0435\u043c \u043f\u0440\u0435\u0434\u043b\u043e\u0436\u0435\u043d\u0438\u0439, \u043d\u0435 \u043f\u0440\u043e\u0433\u043b\u044f\u0434\u044b\u0432\u0430\u0439\u0442\u0435 \u0438\u0445 \u0432\u0441\u043a\u043e\u043b\u044c\u0437\u044c.",faq:[["\u042d\u0442\u043e \u0442\u043e \u0436\u0435 \u0441\u0430\u043c\u043e\u0435, \u0447\u0442\u043e \u043f\u0440\u043e\u0441\u0442\u043e \u0437\u0430\u0443\u0447\u0438\u0442\u044c \u0441\u043f\u0438\u0441\u043e\u043a \u0441\u043b\u043e\u0432?","\u041d\u0435\u0442. \u041f\u0440\u043e\u0441\u0442\u043e\u0439 \u0441\u043f\u0438\u0441\u043e\u043a \u043f\u0440\u043e\u0432\u0435\u0440\u044f\u0435\u0442 \u0442\u043e\u043b\u044c\u043a\u043e \u0445\u0440\u0430\u043d\u0435\u043d\u0438\u0435; \xabReading Span\xbb \u0437\u0430\u0441\u0442\u0430\u0432\u043b\u044f\u0435\u0442 \u043e\u0431\u0440\u0430\u0431\u0430\u0442\u044b\u0432\u0430\u0442\u044c \u043a\u0430\u0436\u0434\u043e\u0435 \u043f\u0440\u0435\u0434\u043b\u043e\u0436\u0435\u043d\u0438\u0435 \u043e\u0434\u043d\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u043e \u0441 \u0443\u0434\u0435\u0440\u0436\u0430\u043d\u0438\u0435\u043c \u0441\u043b\u043e\u0432, \u0438 \u0438\u043c\u0435\u043d\u043d\u043e \u044d\u0442\u043e \u0434\u0435\u043b\u0430\u0435\u0442 \u0437\u0430\u0434\u0430\u0447\u0443 \u043c\u0435\u0440\u043e\u0439 \u0440\u0430\u0431\u043e\u0447\u0435\u0439 \u043f\u0430\u043c\u044f\u0442\u0438, \u0430 \u043d\u0435 \u043e\u0431\u044b\u0447\u043d\u043e\u0439 \u043a\u0440\u0430\u0442\u043a\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u043e\u0439."],["\u041f\u043e\u0434\u043d\u0438\u043c\u0435\u0442 \u043b\u0438 \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0430 \u043c\u043e\u0439 IQ, \u0441\u0442\u0430\u043d\u0443 \u043b\u0438 \u044f \u0443\u043c\u043d\u0435\u0435 \u0432 \u0446\u0435\u043b\u043e\u043c?","\u0427\u0435\u0441\u0442\u043d\u043e \u2014 \u0441\u043a\u043e\u0440\u0435\u0435 \u0432\u0441\u0435\u0433\u043e \u043d\u0435\u0442. \u0412\u044b \u0441\u0442\u0430\u043d\u0435\u0442\u0435 \u043b\u0443\u0447\u0448\u0435 \u0432 \u0441\u0430\u043c\u043e\u0439 \u0437\u0430\u0434\u0430\u0447\u0435 \u0438 \u0432 \u043f\u043e\u0445\u043e\u0436\u0438\u0445 \u043d\u0430 \u043d\u0435\u0451, \u043d\u043e \u043b\u0443\u0447\u0448\u0438\u0435 \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u0438\u0440\u0443\u0435\u043c\u044b\u0435 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u044f \u043f\u043e\u043a\u0430\u0437\u044b\u0432\u0430\u044e\u0442 \u0441\u043b\u0430\u0431\u044b\u0439 \u043f\u0435\u0440\u0435\u043d\u043e\u0441 \u0438\u043b\u0438 \u0435\u0433\u043e \u043e\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0435 \u043d\u0430 \u043e\u0431\u0449\u0438\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0438 \u043d\u0435 \u0441\u0432\u044f\u0437\u0430\u043d\u043d\u044b\u0435 \u0441 \u0437\u0430\u0434\u0430\u0447\u0435\u0439 \u043f\u043e\u0432\u0441\u0435\u0434\u043d\u0435\u0432\u043d\u044b\u0435 \u043d\u0430\u0432\u044b\u043a\u0438."],["\u041c\u043e\u0436\u0435\u0442, \u0447\u0438\u0442\u0430\u0442\u044c \u0431\u044b\u0441\u0442\u0440\u0435\u0435, \u0447\u0442\u043e\u0431\u044b \u0431\u044b\u043b\u043e \u043b\u0435\u0433\u0447\u0435?","\u0421\u043f\u0435\u0448\u043a\u0430 \u043e\u0431\u044b\u0447\u043d\u043e \u0432\u0440\u0435\u0434\u0438\u0442. \u0421\u043b\u043e\u0436\u043d\u043e\u0441\u0442\u044c \u043a\u0430\u043a \u0440\u0430\u0437 \u0432 \u0441\u043e\u0447\u0435\u0442\u0430\u043d\u0438\u0438 \u0447\u0442\u0435\u043d\u0438\u044f \u0438 \u0437\u0430\u043f\u043e\u043c\u0438\u043d\u0430\u043d\u0438\u044f, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u0447\u0438\u0442\u0430\u0439\u0442\u0435 \u0432 \u0440\u0435\u0430\u043b\u044c\u043d\u043e\u043c \u0442\u0435\u043c\u043f\u0435, \u0430 \u0441\u0438\u043b\u044b \u0442\u0440\u0430\u0442\u044c\u0442\u0435 \u043d\u0430 \u043f\u0440\u0438\u0432\u044f\u0437\u043a\u0443 \u043a\u0430\u0436\u0434\u043e\u0433\u043e \u0441\u043b\u043e\u0432\u0430 \u043a \u0435\u0433\u043e \u043f\u0440\u0435\u0434\u043b\u043e\u0436\u0435\u043d\u0438\u044e, \u0430 \u043d\u0435 \u043d\u0430 \u0433\u043e\u043d\u043a\u0443."]],variants:"\u0411\u043b\u0438\u0437\u043a\u0438\u0435 \u0432\u0435\u0440\u0441\u0438\u0438 \u043c\u0435\u043d\u044f\u044e\u0442 \u0437\u0430\u0434\u0430\u0447\u0443-\u043e\u0431\u0440\u0430\u0431\u043e\u0442\u043a\u0443: \u0432 operation span \u0441\u043b\u043e\u0432\u0430 \u0447\u0435\u0440\u0435\u0434\u0443\u044e\u0442\u0441\u044f \u0441 \u043f\u0440\u0438\u043c\u0435\u0440\u0430\u043c\u0438, \u0432 symmetry span \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u044e\u0442\u0441\u044f \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0435 \u043e\u0446\u0435\u043d\u043a\u0438, \u0430 \u0432 listening span \u043f\u0440\u0435\u0434\u043b\u043e\u0436\u0435\u043d\u0438\u044f \u043d\u0435 \u0447\u0438\u0442\u0430\u044e\u0442, \u0430 \u0441\u043b\u0443\u0448\u0430\u044e\u0442. \u0412\u0430\u0440\u0438\u0430\u043d\u0442\u044b \u0442\u0430\u043a\u0436\u0435 \u0440\u0430\u0437\u043b\u0438\u0447\u0430\u044e\u0442\u0441\u044f \u0442\u0435\u043c, \u043d\u0430\u0434\u043e \u043b\u0438 \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0438\u0442\u044c \u0441\u043b\u043e\u0432\u0430 \u043f\u043e \u043f\u043e\u0440\u044f\u0434\u043a\u0443, \u043d\u0443\u0436\u043d\u043e \u043b\u0438 \u043e\u0446\u0435\u043d\u0438\u0432\u0430\u0442\u044c \u043f\u0440\u0435\u0434\u043b\u043e\u0436\u0435\u043d\u0438\u044f \u043a\u0430\u043a \u0432\u0435\u0440\u043d\u044b\u0435 \u0438\u043b\u0438 \u043d\u0435\u0432\u0435\u0440\u043d\u044b\u0435, \u0438 \u043a\u0430\u043a \u0432\u044b\u0441\u0442\u0440\u043e\u0435\u043d\u044b \u0434\u043b\u0438\u043d\u044b \u0441\u0435\u0440\u0438\u0439."},en:{about:"Reading Span shows you a short sentence to read (and often to judge as making sense or not), then a single word to hold onto. After a run of two, three or more sentences you have to recall those words in the order they appeared. The trick is doing both at once: process each sentence while the earlier words sit in memory, and the set size keeps growing.",benefit:"It loads working memory, specifically your ability to hold information while doing something else with your attention at the same time. That dual demand of storage plus processing is what separates it from a plain word list and is closely tied to verbal comprehension.",history:"It began as a laboratory measure of working memory, not a game. After Daneman and Carpenter introduced it in 1980, the idea spread fast: Turner and Engle showed in 1989 that the sentence-reading part could be swapped for arithmetic (the operation span), and a whole family of computer-based complex span tasks followed, becoming standard tools in cognitive psychology.",creator:"Created by Meredyth Daneman and Patricia A. Carpenter in 1980, in their paper in the Journal of Verbal Learning and Verbal Behavior. It is widely credited as the first complex span task, alongside their listening span version.",methods:"Read or judge each sentence at a normal, honest pace instead of rushing the processing part to protect the words, since the difficulty lives in doing both together. Don't just chant the words on a loop; tie each one to its sentence or build a quick mental image or story linking them. Push the set size up only once you are reliable at the current length.",duration:"Short focused blocks work best: around 10 to 15 minutes, a few times a week. Fatigue hits this task quickly, so stop when your accuracy starts sliding rather than grinding through tired.",research:"Evidence is strongest for exactly what you would expect: reading span is a solid, well-validated measure of working memory capacity, and scores correlate with reading comprehension. What it does not reliably do is make you broadly smarter. Large meta-analyses and controlled studies of working memory training (Melby-Lerv\xe5g and colleagues, Redick and colleagues) found that gains stay close to the trained task and do not transfer to fluid intelligence or everyday cognition, so treat any plus-IQ promise with caution.",rec:"Use it to sharpen and gauge your working memory honestly, not as a shortcut to a higher IQ, and keep the sentence-reading part genuine rather than skimming it.",faq:[["Is this the same as just memorising a list of words?","No. A plain list only tests storage; Reading Span forces you to process each sentence at the same time as holding the words, which is what makes it a measure of working memory rather than simple short-term memory."],["Will training this raise my IQ or make me smarter overall?","Honestly, probably not. You will get better at the task and at similar span tasks, but the best controlled research shows little to no transfer to general intelligence or unrelated everyday skills."],["Should I read fast to make it easier?","Rushing usually backfires. The challenge is the combination of reading and remembering, so read at a real pace and spend your effort linking each word to its sentence instead of racing through."]],variants:"Close relatives swap the processing task: operation span pairs words with math problems, symmetry span uses visual judgments, and listening span has you hear sentences instead of reading them. Versions also differ in whether you recall words in order, whether sentences must be judged true or false, and how the set sizes are arranged."},es:{about:"Amplitud de Lectura te muestra una frase corta para leer (y a menudo para juzgar si tiene sentido o no) y luego una sola palabra que debes retener. Tras una serie de dos, tres o m\xe1s frases tienes que recordar esas palabras en el orden en que aparecieron. El truco est\xe1 en hacer ambas cosas a la vez: procesar cada frase mientras las palabras anteriores siguen en la memoria, y la cantidad del conjunto no deja de crecer.",benefit:"Pone a trabajar la memoria de trabajo, en concreto tu capacidad de retener informaci\xf3n mientras haces otra cosa con tu atenci\xf3n al mismo tiempo. Esa doble exigencia de almacenamiento m\xe1s procesamiento es lo que la diferencia de una simple lista de palabras y est\xe1 estrechamente ligada a la comprensi\xf3n verbal.",history:"Empez\xf3 como una medida de laboratorio de la memoria de trabajo, no como un juego. Despu\xe9s de que Daneman y Carpenter la presentaran en 1980, la idea se extendi\xf3 deprisa: Turner y Engle demostraron en 1989 que la parte de leer frases pod\xeda sustituirse por aritm\xe9tica (la amplitud de operaciones), y sigui\xf3 toda una familia de tareas de amplitud compleja basadas en ordenador, que se convirtieron en herramientas est\xe1ndar de la psicolog\xeda cognitiva.",creator:"Creada por Meredyth Daneman y Patricia A. Carpenter en 1980, en su art\xedculo en el Journal of Verbal Learning and Verbal Behavior. Se le atribuye ampliamente ser la primera tarea de amplitud compleja, junto con su versi\xf3n de amplitud de escucha.",methods:"Lee o juzga cada frase a un ritmo normal y honesto en lugar de acelerar el procesamiento para proteger las palabras, ya que la dificultad reside en hacer ambas cosas a la vez. No te limites a repetir las palabras en bucle; liga cada una a su frase o construye una imagen mental r\xe1pida o una historia que las conecte. Sube la cantidad del conjunto solo cuando seas fiable en la longitud actual.",duration:"Los bloques cortos y concentrados funcionan mejor: alrededor de 10 a 15 minutos, varias veces por semana. La fatiga llega r\xe1pido en esta tarea, as\xed que para cuando tu precisi\xf3n empiece a caer en lugar de seguir adelante cansado.",research:"La evidencia es m\xe1s s\xf3lida justo en lo que cabr\xeda esperar: la amplitud de lectura es una medida fiable y bien validada de la capacidad de memoria de trabajo, y las puntuaciones correlacionan con la comprensi\xf3n lectora. Lo que no hace de forma fiable es volverte m\xe1s inteligente en general. Grandes metaan\xe1lisis y estudios controlados sobre entrenamiento de la memoria de trabajo (Melby-Lerv\xe5g y colaboradores, Redick y colaboradores) hallaron que las mejoras se quedan cerca de la tarea entrenada y no se transfieren a la inteligencia fluida ni a la cognici\xf3n cotidiana, as\xed que toma con cautela cualquier promesa de subir el CI.",rec:"\xdasala para afinar y medir tu memoria de trabajo con honestidad, no como un atajo hacia un CI m\xe1s alto, y mant\xe9n genuina la parte de leer frases en lugar de leerla por encima.",faq:[["\xbfEs lo mismo que memorizar una lista de palabras?","No. Una simple lista solo pone a prueba el almacenamiento; Amplitud de Lectura te obliga a procesar cada frase al mismo tiempo que retienes las palabras, que es lo que la convierte en una medida de la memoria de trabajo y no de la simple memoria a corto plazo."],["\xbfEntrenar esto subir\xe1 mi CI o me har\xe1 m\xe1s inteligente en general?","Honestamente, probablemente no. Mejorar\xe1s en la tarea y en tareas de amplitud similares, pero la mejor investigaci\xf3n controlada muestra poca o ninguna transferencia a la inteligencia general ni a habilidades cotidianas no relacionadas."],["\xbfDeber\xeda leer r\xe1pido para que sea m\xe1s f\xe1cil?","Apresurarse suele salir mal. El reto es la combinaci\xf3n de leer y recordar, as\xed que lee a un ritmo real y dedica tu esfuerzo a ligar cada palabra a su frase en vez de correr."]],variants:"Sus parientes cercanos cambian la tarea de procesamiento: la amplitud de operaciones empareja palabras con problemas de matem\xe1ticas, la amplitud de simetr\xeda usa juicios visuales, y la amplitud de escucha hace que oigas las frases en lugar de leerlas. Las versiones tambi\xe9n difieren en si recuerdas las palabras en orden, si las frases deben juzgarse como verdaderas o falsas, y en c\xf3mo se disponen los tama\xf1os de los conjuntos."},de:{about:"Reading Span zeigt dir einen kurzen Satz zum Lesen (und oft mit der Frage, ob er Sinn ergibt oder nicht), dann ein einzelnes Wort, das du dir merken musst. Nach einer Folge von zwei, drei oder mehr S\xe4tzen sollst du diese W\xf6rter in der Reihenfolge wiedergeben, in der sie erschienen sind. Der Kniff liegt darin, beides gleichzeitig zu tun: jeden Satz zu verarbeiten, w\xe4hrend die vorherigen W\xf6rter im Ged\xe4chtnis liegen \u2013 und die Set-Gr\xf6\xdfe w\xe4chst stetig.",benefit:"Es belastet das Arbeitsged\xe4chtnis, konkret deine F\xe4higkeit, Informationen festzuhalten, w\xe4hrend deine Aufmerksamkeit gleichzeitig mit etwas anderem besch\xe4ftigt ist. Genau diese Doppelanforderung aus Speichern und Verarbeiten unterscheidet die Aufgabe von einer schlichten Wortliste und ist eng mit dem verbalen Textverst\xe4ndnis verkn\xfcpft.",history:"Es entstand als laborgest\xfctztes Ma\xdf f\xfcr das Arbeitsged\xe4chtnis, nicht als Spiel. Nachdem Daneman und Carpenter es 1980 einf\xfchrten, verbreitete sich die Idee rasch: Turner und Engle zeigten 1989, dass sich der Satz-Lese-Teil durch Rechenaufgaben ersetzen l\xe4sst (der Operation Span), und es folgte eine ganze Familie computergest\xfctzter komplexer Span-Aufgaben, die zu Standardwerkzeugen der kognitiven Psychologie wurden.",creator:"Entwickelt von Meredyth Daneman und Patricia A. Carpenter im Jahr 1980, in ihrem Aufsatz im Journal of Verbal Learning and Verbal Behavior. Sie gilt weithin als die erste komplexe Span-Aufgabe, neben ihrer Variante des Listening Span.",methods:"Lies oder beurteile jeden Satz in einem normalen, ehrlichen Tempo, statt den Verarbeitungsteil zu \xfcberst\xfcrzen, um die W\xf6rter zu sch\xfctzen \u2013 denn die Schwierigkeit liegt genau darin, beides zusammen zu tun. Leiere die W\xf6rter nicht blo\xdf in einer Schleife herunter; verkn\xfcpfe jedes mit seinem Satz oder baue ein schnelles inneres Bild oder eine kleine Geschichte, die sie verbindet. Erh\xf6he die Set-Gr\xf6\xdfe erst dann, wenn du bei der aktuellen L\xe4nge zuverl\xe4ssig bist.",duration:"Kurze, konzentrierte Bl\xf6cke funktionieren am besten: rund 10 bis 15 Minuten, ein paar Mal pro Woche. Bei dieser Aufgabe setzt die Erm\xfcdung schnell ein, also h\xf6re auf, sobald deine Genauigkeit nachl\xe4sst, statt ersch\xf6pft weiterzumachen.",research:"Am st\xe4rksten ist die Beleglage genau f\xfcr das, was man erwarten w\xfcrde: Reading Span ist ein solides, gut validiertes Ma\xdf f\xfcr die Kapazit\xe4t des Arbeitsged\xe4chtnisses, und die Werte korrelieren mit dem Leseverst\xe4ndnis. Was es nicht zuverl\xe4ssig leistet, ist, dich allgemein kl\xfcger zu machen. Gro\xdfe Metaanalysen und kontrollierte Studien zum Arbeitsged\xe4chtnistraining (Melby-Lerv\xe5g und Kollegen, Redick und Kollegen) fanden, dass die Zugewinne nahe an der trainierten Aufgabe bleiben und sich nicht auf die fluide Intelligenz oder das allt\xe4gliche Denken \xfcbertragen \u2013 nimm jedes Plus-IQ-Versprechen also mit Vorsicht.",rec:"Nutze es, um dein Arbeitsged\xe4chtnis ehrlich zu sch\xe4rfen und einzusch\xe4tzen, nicht als Abk\xfcrzung zu einem h\xf6heren IQ, und halte den Satz-Lese-Teil echt, statt ihn nur zu \xfcberfliegen.",faq:[["Ist das dasselbe wie das blo\xdfe Auswendiglernen einer Wortliste?","Nein. Eine schlichte Liste pr\xfcft nur das Speichern; Reading Span zwingt dich, jeden Satz gleichzeitig zu verarbeiten, w\xe4hrend du die W\xf6rter beh\xe4ltst \u2013 und genau das macht es zu einem Ma\xdf des Arbeitsged\xe4chtnisses statt des einfachen Kurzzeitged\xe4chtnisses."],["Erh\xf6ht das Training meinen IQ oder macht es mich insgesamt kl\xfcger?","Ehrlich gesagt wahrscheinlich nicht. Du wirst in der Aufgabe und in \xe4hnlichen Span-Aufgaben besser, aber die besten kontrollierten Untersuchungen zeigen kaum bis keinen Transfer auf die allgemeine Intelligenz oder auf unabh\xe4ngige Alltagsf\xe4higkeiten."],["Sollte ich schnell lesen, um es mir leichter zu machen?","Hetzen geht meist nach hinten los. Die Herausforderung ist die Kombination aus Lesen und Behalten, also lies in einem echten Tempo und stecke deine M\xfche darin, jedes Wort mit seinem Satz zu verkn\xfcpfen, statt durchzurasen."]],variants:"Nahe Verwandte tauschen die Verarbeitungsaufgabe aus: Operation Span koppelt W\xf6rter mit Rechenaufgaben, Symmetry Span nutzt visuelle Urteile, und beim Listening Span h\xf6rst du die S\xe4tze, statt sie zu lesen. Die Versionen unterscheiden sich au\xdferdem darin, ob du die W\xf6rter in Reihenfolge wiedergibst, ob S\xe4tze als wahr oder falsch beurteilt werden m\xfcssen und wie die Set-Gr\xf6\xdfen angeordnet sind."},pt:{about:"O Reading Span mostra uma frase curta para ler (e muitas vezes para julgar se faz sentido ou n\xe3o) e, em seguida, uma \xfanica palavra para guardar. Depois de uma sequ\xeancia de duas, tr\xeas ou mais frases, voc\xea precisa recordar essas palavras na ordem em que apareceram. O truque \xe9 fazer as duas coisas ao mesmo tempo: processar cada frase enquanto as palavras anteriores ficam na mem\xf3ria, e o tamanho do conjunto n\xe3o para de crescer.",benefit:"Ele sobrecarrega a mem\xf3ria de trabalho, especificamente a sua capacidade de reter informa\xe7\xe3o enquanto faz outra coisa com a aten\xe7\xe3o ao mesmo tempo. Essa dupla exig\xeancia de armazenar e processar \xe9 o que o separa de uma simples lista de palavras e est\xe1 intimamente ligada \xe0 compreens\xe3o verbal.",history:"Come\xe7ou como uma medida de laborat\xf3rio da mem\xf3ria de trabalho, n\xe3o como um jogo. Depois que Daneman e Carpenter o introduziram em 1980, a ideia se espalhou depressa: Turner e Engle mostraram em 1989 que a parte de leitura de frases podia ser trocada por aritm\xe9tica (o operation span), e seguiu-se toda uma fam\xedlia de tarefas computadorizadas de span complexo, que se tornaram ferramentas padr\xe3o na psicologia cognitiva.",creator:"Criado por Meredyth Daneman e Patricia A. Carpenter em 1980, em seu artigo no Journal of Verbal Learning and Verbal Behavior. \xc9 amplamente reconhecido como a primeira tarefa de span complexo, ao lado da vers\xe3o de listening span dos mesmos autores.",methods:"Leia ou julgue cada frase num ritmo normal e honesto, em vez de acelerar a parte de processamento para proteger as palavras, j\xe1 que a dificuldade est\xe1 justamente em fazer as duas coisas juntas. N\xe3o fique s\xf3 repetindo as palavras em loop; ligue cada uma \xe0 sua frase ou crie rapidamente uma imagem mental ou uma hist\xf3ria que as conecte. S\xf3 aumente o tamanho do conjunto quando estiver confi\xe1vel no comprimento atual.",duration:"Blocos curtos e concentrados funcionam melhor: por volta de 10 a 15 minutos, algumas vezes por semana. A fadiga chega r\xe1pido nessa tarefa, ent\xe3o pare quando a sua precis\xe3o come\xe7ar a cair, em vez de insistir cansado.",research:"As evid\xeancias s\xe3o mais fortes exatamente para o que se espera: o reading span \xe9 uma medida s\xf3lida e bem validada da capacidade de mem\xf3ria de trabalho, e as pontua\xe7\xf5es se correlacionam com a compreens\xe3o de leitura. O que ele n\xe3o faz de forma confi\xe1vel \xe9 deixar voc\xea mais inteligente em geral. Grandes meta-an\xe1lises e estudos controlados de treino de mem\xf3ria de trabalho (Melby-Lerv\xe5g e colegas, Redick e colegas) mostraram que os ganhos ficam restritos \xe0 tarefa treinada e n\xe3o se transferem para a intelig\xeancia fluida ou para a cogni\xe7\xe3o do dia a dia, ent\xe3o encare com cautela qualquer promessa de aumento de QI.",rec:"Use-o para agu\xe7ar e medir a sua mem\xf3ria de trabalho com honestidade, n\xe3o como atalho para um QI maior, e mantenha a parte de leitura das frases genu\xedna, em vez de s\xf3 passar os olhos por elas.",faq:[["Isso \xe9 a mesma coisa que s\xf3 memorizar uma lista de palavras?","N\xe3o. Uma lista simples s\xf3 testa o armazenamento; o Reading Span obriga voc\xea a processar cada frase ao mesmo tempo em que ret\xe9m as palavras, e \xe9 isso que faz dele uma medida de mem\xf3ria de trabalho, e n\xe3o de mem\xf3ria de curto prazo simples."],["Treinar isso vai aumentar o meu QI ou me deixar mais inteligente no geral?","Honestamente, provavelmente n\xe3o. Voc\xea vai ficar melhor na tarefa e em tarefas de span parecidas, mas as melhores pesquisas controladas mostram pouca ou nenhuma transfer\xeancia para a intelig\xeancia geral ou para habilidades do dia a dia n\xe3o relacionadas."],["Devo ler r\xe1pido para facilitar?","Apressar-se costuma sair pela culatra. O desafio \xe9 a combina\xe7\xe3o de ler e lembrar, ent\xe3o leia num ritmo de verdade e gaste o seu esfor\xe7o ligando cada palavra \xe0 sua frase, em vez de correr."]],variants:"Parentes pr\xf3ximos trocam a tarefa de processamento: o operation span junta palavras a problemas de matem\xe1tica, o symmetry span usa julgamentos visuais e o listening span faz voc\xea ouvir as frases em vez de l\xea-las. As vers\xf5es tamb\xe9m diferem em recordar ou n\xe3o as palavras em ordem, em as frases precisarem ou n\xe3o ser julgadas como verdadeiras ou falsas, e em como os tamanhos dos conjuntos s\xe3o organizados."},hi:{about:"Reading Span \u0906\u092a\u0915\u094b \u092a\u0922\u093c\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u090f\u0915 \u091b\u094b\u091f\u093e \u0935\u093e\u0915\u094d\u092f \u0926\u093f\u0916\u093e\u0924\u093e \u0939\u0948 (\u0914\u0930 \u0905\u0915\u094d\u0938\u0930 \u092f\u0939 \u0924\u092f \u0915\u0930\u0928\u0947 \u0915\u094b \u0915\u0939\u0924\u093e \u0939\u0948 \u0915\u093f \u0909\u0938\u0915\u093e \u0915\u094b\u0908 \u0905\u0930\u094d\u0925 \u092c\u0928\u0924\u093e \u0939\u0948 \u092f\u093e \u0928\u0939\u0940\u0902), \u092b\u093f\u0930 \u092f\u093e\u0926 \u0930\u0916\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u090f\u0915 \u0905\u0915\u0947\u0932\u093e \u0936\u092c\u094d\u0926 \u0926\u0947\u0924\u093e \u0939\u0948\u0964 \u0926\u094b, \u0924\u0940\u0928 \u092f\u093e \u0909\u0938\u0938\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0935\u093e\u0915\u094d\u092f\u094b\u0902 \u0915\u0947 \u090f\u0915 \u0926\u094c\u0930 \u0915\u0947 \u092c\u093e\u0926 \u0906\u092a\u0915\u094b \u0935\u0947 \u0936\u092c\u094d\u0926 \u0909\u0938\u0940 \u0915\u094d\u0930\u092e \u092e\u0947\u0902 \u092f\u093e\u0926 \u0915\u0930\u0928\u0947 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902 \u091c\u093f\u0938\u092e\u0947\u0902 \u0935\u0947 \u0906\u090f \u0925\u0947\u0964 \u0905\u0938\u0932\u0940 \u092a\u0947\u091a \u0926\u094b\u0928\u094b\u0902 \u0915\u093e\u092e \u090f\u0915 \u0938\u093e\u0925 \u0915\u0930\u0928\u0947 \u092e\u0947\u0902 \u0939\u0948: \u0939\u0930 \u0935\u093e\u0915\u094d\u092f \u0915\u094b \u0938\u0902\u0938\u093e\u0927\u093f\u0924 \u0915\u0940\u091c\u093f\u090f \u091c\u092c\u0915\u093f \u092a\u093f\u091b\u0932\u0947 \u0936\u092c\u094d\u0926 \u0938\u094d\u092e\u0943\u0924\u093f \u092e\u0947\u0902 \u091f\u093f\u0915\u0947 \u0930\u0939\u0947\u0902, \u0914\u0930 \u0938\u0947\u091f \u0915\u093e \u0906\u0915\u093e\u0930 \u0932\u0917\u093e\u0924\u093e\u0930 \u092c\u0922\u093c\u0924\u093e \u091c\u093e\u0924\u093e \u0939\u0948\u0964",benefit:"\u092f\u0939 \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932 \u0938\u094d\u092e\u0943\u0924\u093f \u092a\u0930 \u092c\u094b\u091d \u0921\u093e\u0932\u0924\u093e \u0939\u0948, \u0916\u093c\u093e\u0938\u0915\u0930 \u0906\u092a\u0915\u0940 \u0909\u0938 \u0915\u094d\u0937\u092e\u0924\u093e \u092a\u0930 \u091c\u094b \u091c\u093e\u0928\u0915\u093e\u0930\u0940 \u0915\u094b \u0925\u093e\u092e\u0947 \u0930\u0916\u0924\u0940 \u0939\u0948 \u091c\u092c\u0915\u093f \u0906\u092a\u0915\u093e \u0927\u094d\u092f\u093e\u0928 \u0938\u093e\u0925-\u0938\u093e\u0925 \u0915\u0941\u091b \u0914\u0930 \u0915\u0930 \u0930\u0939\u093e \u0939\u094b\u0924\u093e \u0939\u0948\u0964 \u092d\u0902\u0921\u093e\u0930\u0923 \u0914\u0930 \u0938\u0902\u0938\u093e\u0927\u0928 \u0915\u0940 \u092f\u0939\u0940 \u0926\u094b\u0939\u0930\u0940 \u092e\u093e\u0901\u0917 \u0907\u0938\u0947 \u090f\u0915 \u0938\u093e\u0926\u0940 \u0936\u092c\u094d\u0926-\u0938\u0942\u091a\u0940 \u0938\u0947 \u0905\u0932\u0917 \u0915\u0930\u0924\u0940 \u0939\u0948 \u0914\u0930 \u092e\u094c\u0916\u093f\u0915 \u0938\u092e\u091d \u0938\u0947 \u0917\u0939\u0930\u093e\u0908 \u0938\u0947 \u091c\u0941\u0921\u093c\u0940 \u0939\u0941\u0908 \u0939\u0948\u0964",history:"\u0907\u0938\u0915\u0940 \u0936\u0941\u0930\u0941\u0906\u0924 \u090f\u0915 \u0916\u0947\u0932 \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u0928\u0939\u0940\u0902, \u092c\u0932\u094d\u0915\u093f \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932 \u0938\u094d\u092e\u0943\u0924\u093f \u0915\u0940 \u090f\u0915 \u092a\u094d\u0930\u092f\u094b\u0917\u0936\u093e\u0932\u093e \u092e\u093e\u092a \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u0939\u0941\u0908\u0964 1980 \u092e\u0947\u0902 Daneman \u0914\u0930 Carpenter \u0926\u094d\u0935\u093e\u0930\u093e \u0907\u0938\u0947 \u092a\u0947\u0936 \u0915\u093f\u090f \u091c\u093e\u0928\u0947 \u0915\u0947 \u092c\u093e\u0926 \u092f\u0939 \u0935\u093f\u091a\u093e\u0930 \u0924\u0947\u091c\u093c\u0940 \u0938\u0947 \u092b\u0948\u0932\u093e: Turner \u0914\u0930 Engle \u0928\u0947 1989 \u092e\u0947\u0902 \u0926\u093f\u0916\u093e\u092f\u093e \u0915\u093f \u0935\u093e\u0915\u094d\u092f-\u092a\u0920\u0928 \u0935\u093e\u0932\u0947 \u0939\u093f\u0938\u094d\u0938\u0947 \u0915\u0940 \u091c\u0917\u0939 \u0905\u0902\u0915\u0917\u0923\u093f\u0924 \u0930\u0916\u093e \u091c\u093e \u0938\u0915\u0924\u093e \u0939\u0948 (the operation span), \u0914\u0930 \u0907\u0938\u0915\u0947 \u092c\u093e\u0926 \u0915\u0902\u092a\u094d\u092f\u0942\u091f\u0930-\u0906\u0927\u093e\u0930\u093f\u0924 \u091c\u091f\u093f\u0932 span \u0915\u093e\u0930\u094d\u092f\u094b\u0902 \u0915\u093e \u090f\u0915 \u092a\u0942\u0930\u093e \u092a\u0930\u093f\u0935\u093e\u0930 \u0906\u092f\u093e, \u091c\u094b \u0938\u0902\u091c\u094d\u091e\u093e\u0928\u093e\u0924\u094d\u092e\u0915 \u092e\u0928\u094b\u0935\u093f\u091c\u094d\u091e\u093e\u0928 \u092e\u0947\u0902 \u092e\u093e\u0928\u0915 \u0909\u092a\u0915\u0930\u0923 \u092c\u0928 \u0917\u090f\u0964",creator:"\u0907\u0938\u0947 1980 \u092e\u0947\u0902 Meredyth Daneman \u0914\u0930 Patricia A. Carpenter \u0928\u0947 Journal of Verbal Learning and Verbal Behavior \u092e\u0947\u0902 \u0905\u092a\u0928\u0947 \u0936\u094b\u0927\u092a\u0924\u094d\u0930 \u092e\u0947\u0902 \u092c\u0928\u093e\u092f\u093e \u0925\u093e\u0964 \u0907\u0938\u0947 \u0909\u0928\u0915\u0947 listening span \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0915\u0947 \u0938\u093e\u0925-\u0938\u093e\u0925 \u0935\u094d\u092f\u093e\u092a\u0915 \u0930\u0942\u092a \u0938\u0947 \u092a\u0939\u0932\u093e \u091c\u091f\u093f\u0932 span \u0915\u093e\u0930\u094d\u092f \u092e\u093e\u0928\u093e \u091c\u093e\u0924\u093e \u0939\u0948\u0964",methods:"\u0936\u092c\u094d\u0926\u094b\u0902 \u0915\u094b \u092c\u091a\u093e\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0938\u0902\u0938\u093e\u0927\u0928 \u0935\u093e\u0932\u0947 \u0939\u093f\u0938\u094d\u0938\u0947 \u092e\u0947\u0902 \u091c\u0932\u094d\u0926\u092c\u093e\u091c\u093c\u0940 \u0915\u0930\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u0939\u0930 \u0935\u093e\u0915\u094d\u092f \u0915\u094b \u0938\u093e\u092e\u093e\u0928\u094d\u092f, \u0908\u092e\u093e\u0928\u0926\u093e\u0930 \u0930\u092b\u093c\u094d\u0924\u093e\u0930 \u0938\u0947 \u092a\u0922\u093c\u093f\u090f \u092f\u093e \u092a\u0930\u0916\u093f\u090f, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u0905\u0938\u0932\u0940 \u0915\u0920\u093f\u0928\u093e\u0908 \u0926\u094b\u0928\u094b\u0902 \u0915\u094b \u090f\u0915 \u0938\u093e\u0925 \u0915\u0930\u0928\u0947 \u092e\u0947\u0902 \u092c\u0938\u0924\u0940 \u0939\u0948\u0964 \u0936\u092c\u094d\u0926\u094b\u0902 \u0915\u094b \u0938\u093f\u0930\u094d\u092b\u093c \u0930\u091f\u094d\u091f\u0947 \u0915\u0940 \u0924\u0930\u0939 \u0926\u094b\u0939\u0930\u093e\u0924\u0947 \u092e\u0924 \u0930\u0939\u093f\u090f; \u0939\u0930 \u0936\u092c\u094d\u0926 \u0915\u094b \u0909\u0938\u0915\u0947 \u0935\u093e\u0915\u094d\u092f \u0938\u0947 \u092c\u093e\u0901\u0927\u093f\u090f \u092f\u093e \u0909\u0928\u094d\u0939\u0947\u0902 \u091c\u094b\u0921\u093c\u0924\u0940 \u0939\u0941\u0908 \u090f\u0915 \u091d\u091f\u092a\u091f \u092e\u093e\u0928\u0938\u093f\u0915 \u091b\u0935\u093f \u092f\u093e \u0915\u0939\u093e\u0928\u0940 \u092c\u0928\u093e\u0907\u090f\u0964 \u0938\u0947\u091f \u0915\u093e \u0906\u0915\u093e\u0930 \u0924\u092d\u0940 \u092c\u0922\u093c\u093e\u0907\u090f \u091c\u092c \u0906\u092a \u092e\u094c\u091c\u0942\u0926\u093e \u0932\u0902\u092c\u093e\u0908 \u092a\u0930 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0939\u094b \u091c\u093e\u090f\u0901\u0964",duration:"\u091b\u094b\u091f\u0947 \u090f\u0915\u093e\u0917\u094d\u0930 \u0916\u0902\u0921 \u0938\u092c\u0938\u0947 \u0905\u091a\u094d\u091b\u0947 \u0930\u0939\u0924\u0947 \u0939\u0948\u0902: \u0915\u0930\u0940\u092c 10 \u0938\u0947 15 \u092e\u093f\u0928\u091f, \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u0915\u0941\u091b \u092c\u093e\u0930\u0964 \u0907\u0938 \u0915\u093e\u092e \u092e\u0947\u0902 \u0925\u0915\u093e\u0928 \u091c\u0932\u094d\u0926\u0940 \u0906\u0924\u0940 \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0925\u0915\u0915\u0930 \u0930\u0917\u0921\u093c\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u091c\u092c \u0906\u092a\u0915\u0940 \u0938\u091f\u0940\u0915\u0924\u093e \u0917\u093f\u0930\u0928\u0947 \u0932\u0917\u0947 \u0924\u092d\u0940 \u0930\u0941\u0915 \u091c\u093e\u0907\u090f\u0964",research:"\u0938\u092c\u0938\u0947 \u092a\u0941\u0916\u093c\u094d\u0924\u093e \u0938\u092c\u0942\u0924 \u0920\u0940\u0915 \u0909\u0938\u0940 \u092c\u093e\u0924 \u0915\u0947 \u0932\u093f\u090f \u0939\u0948 \u091c\u093f\u0938\u0915\u0940 \u0906\u092a \u0909\u092e\u094d\u092e\u0940\u0926 \u0915\u0930\u0947\u0902\u0917\u0947: reading span \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932 \u0938\u094d\u092e\u0943\u0924\u093f \u0915\u0940 \u0915\u094d\u0937\u092e\u0924\u093e \u0915\u0940 \u090f\u0915 \u0920\u094b\u0938, \u0905\u091a\u094d\u091b\u0940 \u0924\u0930\u0939 \u0938\u0947 \u092a\u094d\u0930\u092e\u093e\u0923\u093f\u0924 \u092e\u093e\u092a \u0939\u0948, \u0914\u0930 \u0907\u0938\u0915\u0947 \u0938\u094d\u0915\u094b\u0930 \u092a\u0920\u0928-\u0938\u092e\u091d \u0938\u0947 \u0938\u0939\u0938\u0902\u092c\u0902\u0927\u093f\u0924 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902\u0964 \u091c\u094b \u092f\u0939 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0922\u0902\u0917 \u0938\u0947 \u0928\u0939\u0940\u0902 \u0915\u0930\u0924\u093e, \u0935\u0939 \u0939\u0948 \u0906\u092a\u0915\u094b \u0935\u094d\u092f\u093e\u092a\u0915 \u0930\u0942\u092a \u0938\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u092c\u0941\u0926\u094d\u0927\u093f\u092e\u093e\u0928 \u092c\u0928\u093e\u0928\u093e\u0964 \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932 \u0938\u094d\u092e\u0943\u0924\u093f \u0915\u0940 \u091f\u094d\u0930\u0947\u0928\u093f\u0902\u0917 \u0915\u0947 \u092c\u0921\u093c\u0947 \u092e\u0947\u091f\u093e-\u0935\u093f\u0936\u094d\u0932\u0947\u0937\u0923 \u0914\u0930 \u0928\u093f\u092f\u0902\u0924\u094d\u0930\u093f\u0924 \u0905\u0927\u094d\u092f\u092f\u0928 (Melby-Lerv\xe5g \u0914\u0930 \u0938\u0939\u092f\u094b\u0917\u0940, Redick \u0914\u0930 \u0938\u0939\u092f\u094b\u0917\u0940) \u092a\u093e\u0924\u0947 \u0939\u0948\u0902 \u0915\u093f \u0932\u093e\u092d \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u093f\u090f \u0917\u090f \u0915\u093e\u0930\u094d\u092f \u0915\u0947 \u092a\u093e\u0938 \u0939\u0940 \u0930\u0939\u0924\u0947 \u0939\u0948\u0902 \u0914\u0930 \u0924\u0930\u0932 \u092c\u0941\u0926\u094d\u0927\u093f \u092f\u093e \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0940 \u0938\u094b\u091a \u0924\u0915 \u0928\u0939\u0940\u0902 \u092a\u0939\u0941\u0901\u091a\u0924\u0947, \u0907\u0938\u0932\u093f\u090f \u0915\u093f\u0938\u0940 \u092d\u0940 '\u092c\u0941\u0926\u094d\u0927\u093f-\u092c\u0922\u093c\u093e\u0928\u0947' \u0935\u093e\u0932\u0947 \u0935\u093e\u0926\u0947 \u0915\u094b \u0938\u093e\u0935\u0927\u093e\u0928\u0940 \u0938\u0947 \u0932\u0940\u091c\u093f\u090f\u0964",rec:"\u0907\u0938\u0915\u093e \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0905\u092a\u0928\u0940 \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932 \u0938\u094d\u092e\u0943\u0924\u093f \u0915\u094b \u0908\u092e\u093e\u0928\u0926\u093e\u0930\u0940 \u0938\u0947 \u0924\u0947\u091c\u093c \u0915\u0930\u0928\u0947 \u0914\u0930 \u092e\u093e\u092a\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0915\u0940\u091c\u093f\u090f, \u0928 \u0915\u093f \u091c\u093c\u094d\u092f\u093e\u0926\u093e IQ \u0915\u0940 \u0915\u093f\u0938\u0940 \u0936\u0949\u0930\u094d\u091f\u0915\u091f \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902, \u0914\u0930 \u0935\u093e\u0915\u094d\u092f-\u092a\u0920\u0928 \u0935\u093e\u0932\u0947 \u0939\u093f\u0938\u094d\u0938\u0947 \u0915\u094b \u0938\u0930\u0938\u0930\u0940 \u0924\u094c\u0930 \u092a\u0930 \u092a\u0922\u093c\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u0938\u091a\u092e\u0941\u091a \u092a\u0922\u093c\u093f\u090f\u0964",faq:[["\u0915\u094d\u092f\u093e \u092f\u0939 \u092c\u0938 \u0936\u092c\u094d\u0926\u094b\u0902 \u0915\u0940 \u090f\u0915 \u0938\u0942\u091a\u0940 \u0930\u091f\u0928\u0947 \u091c\u0948\u0938\u093e \u0939\u0940 \u0939\u0948?","\u0928\u0939\u0940\u0902\u0964 \u090f\u0915 \u0938\u093e\u0926\u0940 \u0938\u0942\u091a\u0940 \u0938\u093f\u0930\u094d\u092b\u093c \u092d\u0902\u0921\u093e\u0930\u0923 \u0915\u094b \u092a\u0930\u0916\u0924\u0940 \u0939\u0948; Reading Span \u0906\u092a\u0915\u094b \u0936\u092c\u094d\u0926\u094b\u0902 \u0915\u094b \u0925\u093e\u092e\u0947 \u0930\u0916\u0928\u0947 \u0915\u0947 \u0938\u093e\u0925-\u0938\u093e\u0925 \u0939\u0930 \u0935\u093e\u0915\u094d\u092f \u0915\u094b \u0938\u0902\u0938\u093e\u0927\u093f\u0924 \u0915\u0930\u0928\u0947 \u092a\u0930 \u092e\u091c\u092c\u0942\u0930 \u0915\u0930\u0924\u093e \u0939\u0948, \u0914\u0930 \u092f\u0939\u0940 \u091a\u0940\u091c\u093c \u0907\u0938\u0947 \u0938\u0930\u0932 \u0905\u0932\u094d\u092a\u0915\u093e\u0932\u093f\u0915 \u0938\u094d\u092e\u0943\u0924\u093f \u0915\u0947 \u092c\u091c\u093e\u092f \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932 \u0938\u094d\u092e\u0943\u0924\u093f \u0915\u0940 \u092e\u093e\u092a \u092c\u0928\u093e\u0924\u0940 \u0939\u0948\u0964"],["\u0915\u094d\u092f\u093e \u0907\u0938\u0915\u0940 \u091f\u094d\u0930\u0947\u0928\u093f\u0902\u0917 \u0938\u0947 \u092e\u0947\u0930\u093e IQ \u092c\u0922\u093c\u0947\u0917\u093e \u092f\u093e \u092e\u0948\u0902 \u0915\u0941\u0932 \u092e\u093f\u0932\u093e\u0915\u0930 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0939\u094b\u0936\u093f\u092f\u093e\u0930 \u092c\u0928\u0942\u0901\u0917\u093e?","\u0908\u092e\u093e\u0928\u0926\u093e\u0930\u0940 \u0938\u0947 \u0915\u0939\u0947\u0902 \u0924\u094b, \u0936\u093e\u092f\u0926 \u0928\u0939\u0940\u0902\u0964 \u0906\u092a \u0907\u0938 \u0915\u093e\u092e \u092e\u0947\u0902 \u0914\u0930 \u0907\u0938\u0938\u0947 \u092e\u093f\u0932\u0924\u0947-\u091c\u0941\u0932\u0924\u0947 span \u0915\u093e\u0930\u094d\u092f\u094b\u0902 \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u090f\u0901\u0917\u0947, \u092a\u0930 \u0938\u092c\u0938\u0947 \u0905\u091a\u094d\u091b\u0947 \u0928\u093f\u092f\u0902\u0924\u094d\u0930\u093f\u0924 \u0936\u094b\u0927 \u0926\u093f\u0916\u093e\u0924\u0947 \u0939\u0948\u0902 \u0915\u093f \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u092c\u0941\u0926\u094d\u0927\u093f \u092f\u093e \u0905\u0938\u0902\u092c\u0902\u0927\u093f\u0924 \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0947 \u0915\u094c\u0936\u0932\u094b\u0902 \u0924\u0915 \u092c\u0939\u0941\u0924 \u0915\u092e \u092f\u093e \u0915\u094b\u0908 \u091f\u094d\u0930\u093e\u0902\u0938\u092b\u093c\u0930 \u0928\u0939\u0940\u0902 \u0939\u094b\u0924\u093e\u0964"],["\u0915\u094d\u092f\u093e \u0907\u0938\u0947 \u0906\u0938\u093e\u0928 \u092c\u0928\u093e\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u092e\u0941\u091d\u0947 \u0924\u0947\u091c\u093c \u092a\u0922\u093c\u0928\u093e \u091a\u093e\u0939\u093f\u090f?","\u091c\u0932\u094d\u0926\u092c\u093e\u091c\u093c\u0940 \u0906\u092e \u0924\u094c\u0930 \u092a\u0930 \u0909\u0932\u091f\u0940 \u092a\u0921\u093c\u0924\u0940 \u0939\u0948\u0964 \u091a\u0941\u0928\u094c\u0924\u0940 \u092a\u0922\u093c\u0928\u0947 \u0914\u0930 \u092f\u093e\u0926 \u0930\u0916\u0928\u0947 \u0915\u0947 \u092e\u0947\u0932 \u092e\u0947\u0902 \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0905\u0938\u0932\u0940 \u0930\u092b\u093c\u094d\u0924\u093e\u0930 \u0938\u0947 \u092a\u0922\u093c\u093f\u090f \u0914\u0930 \u0905\u092a\u0928\u0940 \u092e\u0947\u0939\u0928\u0924 \u0939\u0930 \u0936\u092c\u094d\u0926 \u0915\u094b \u0909\u0938\u0915\u0947 \u0935\u093e\u0915\u094d\u092f \u0938\u0947 \u091c\u094b\u0921\u093c\u0928\u0947 \u092e\u0947\u0902 \u0932\u0917\u093e\u0907\u090f, \u0928 \u0915\u093f \u0938\u0930\u092a\u091f \u0926\u094c\u0921\u093c\u0928\u0947 \u092e\u0947\u0902\u0964"]],variants:"\u0928\u091c\u093c\u0926\u0940\u0915\u0940 \u0930\u093f\u0936\u094d\u0924\u0947\u0926\u093e\u0930 \u0938\u0902\u0938\u093e\u0927\u0928-\u0915\u093e\u0930\u094d\u092f \u0915\u094b \u092c\u0926\u0932 \u0926\u0947\u0924\u0947 \u0939\u0948\u0902: operation span \u0936\u092c\u094d\u0926\u094b\u0902 \u0915\u094b \u0917\u0923\u093f\u0924 \u0915\u0940 \u0938\u092e\u0938\u094d\u092f\u093e\u0913\u0902 \u0915\u0947 \u0938\u093e\u0925 \u091c\u094b\u0921\u093c\u0924\u093e \u0939\u0948, symmetry span \u0926\u0943\u0936\u094d\u092f \u0928\u093f\u0930\u094d\u0923\u092f\u094b\u0902 \u0915\u093e \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0915\u0930\u0924\u093e \u0939\u0948, \u0914\u0930 listening span \u092e\u0947\u0902 \u0906\u092a \u0935\u093e\u0915\u094d\u092f \u092a\u0922\u093c\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u0938\u0941\u0928\u0924\u0947 \u0939\u0948\u0902\u0964 \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0907\u0938\u092e\u0947\u0902 \u092d\u0940 \u0905\u0932\u0917 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902 \u0915\u093f \u0936\u092c\u094d\u0926 \u0915\u094d\u0930\u092e \u092e\u0947\u0902 \u092f\u093e\u0926 \u0915\u0930\u0928\u0947 \u0939\u0948\u0902 \u092f\u093e \u0928\u0939\u0940\u0902, \u0935\u093e\u0915\u094d\u092f\u094b\u0902 \u0915\u094b \u0938\u0939\u0940 \u092f\u093e \u0917\u093c\u0932\u0924 \u0906\u0901\u0915\u0928\u093e \u0939\u0948 \u092f\u093e \u0928\u0939\u0940\u0902, \u0914\u0930 \u0938\u0947\u091f \u0915\u0947 \u0906\u0915\u093e\u0930 \u0915\u0948\u0938\u0947 \u0935\u094d\u092f\u0935\u0938\u094d\u0925\u093f\u0924 \u0915\u093f\u090f \u0917\u090f \u0939\u0948\u0902\u0964"},zh:{about:"\u300c\u9605\u8bfb\u5e7f\u5ea6\u300d\u5148\u7ed9\u4f60\u770b\u4e00\u4e2a\u77ed\u53e5\u8ba9\u4f60\u8bfb\uff08\u901a\u5e38\u8fd8\u8981\u5224\u65ad\u5b83\u662f\u5426\u8bf4\u5f97\u901a\uff09\uff0c\u63a5\u7740\u7ed9\u4f60\u4e00\u4e2a\u5355\u8bcd\u8981\u8bb0\u4f4f\u3002\u8bfb\u5b8c\u8fde\u7740\u4e24\u53e5\u3001\u4e09\u53e5\u4e43\u81f3\u66f4\u591a\u53e5\u4e4b\u540e\uff0c\u4f60\u5f97\u6309\u5b83\u4eec\u51fa\u73b0\u7684\u987a\u5e8f\u628a\u8fd9\u4e9b\u5355\u8bcd\u56de\u5fc6\u51fa\u6765\u3002\u96be\u70b9\u5728\u4e8e\u4e24\u4ef6\u4e8b\u540c\u65f6\u505a\uff1a\u4e00\u8fb9\u5904\u7406\u6bcf\u4e2a\u53e5\u5b50\uff0c\u4e00\u8fb9\u8ba9\u4e4b\u524d\u7684\u5355\u8bcd\u7559\u5728\u8bb0\u5fc6\u91cc\uff0c\u800c\u4e14\u96c6\u5408\u7684\u89c4\u6a21\u8fd8\u5728\u4e0d\u65ad\u53d8\u5927\u3002",benefit:"\u5b83\u7ed9\u5de5\u4f5c\u8bb0\u5fc6\u52a0\u8d1f\u8377\uff0c\u5177\u4f53\u6765\u8bf4\uff0c\u662f\u4f60\u5728\u7528\u6ce8\u610f\u529b\u540c\u65f6\u505a\u522b\u7684\u4e8b\u60c5\u65f6\uff0c\u4ecd\u80fd\u4fdd\u6301\u4fe1\u606f\u7684\u80fd\u529b\u3002\u8fd9\u79cd\u300c\u5b58\u50a8+\u52a0\u5de5\u300d\u7684\u53cc\u91cd\u8981\u6c42\uff0c\u6b63\u662f\u5b83\u533a\u522b\u4e8e\u5355\u7eaf\u80cc\u5355\u8bcd\u6e05\u5355\u4e4b\u5904\uff0c\u800c\u4e14\u4e0e\u8a00\u8bed\u7406\u89e3\u80fd\u529b\u5bc6\u5207\u76f8\u5173\u3002",history:"\u5b83\u4e00\u5f00\u59cb\u662f\u5b9e\u9a8c\u5ba4\u91cc\u6d4b\u91cf\u5de5\u4f5c\u8bb0\u5fc6\u7684\u6307\u6807\uff0c\u800c\u975e\u6e38\u620f\u3002Daneman\u548cCarpenter\u4e8e1980\u5e74\u63d0\u51fa\u540e\uff0c\u8fd9\u4e00\u601d\u8def\u8fc5\u901f\u6269\u6563\uff1aTurner\u548cEngle\u57281989\u5e74\u8868\u660e\uff0c\u8bfb\u53e5\u5b50\u90a3\u90e8\u5206\u53ef\u4ee5\u6362\u6210\u7b97\u672f\uff08\u5373\u8fd0\u7b97\u5e7f\u5ea6\uff0coperation span\uff09\uff0c\u968f\u540e\u4e00\u6574\u4e2a\u5bb6\u65cf\u7684\u3001\u57fa\u4e8e\u8ba1\u7b97\u673a\u7684\u590d\u6742\u5e7f\u5ea6\u4efb\u52a1\u76f8\u7ee7\u51fa\u73b0\uff0c\u6210\u4e3a\u8ba4\u77e5\u5fc3\u7406\u5b66\u7684\u6807\u51c6\u5de5\u5177\u3002",creator:"\u7531Meredyth Daneman\u548cPatricia A. Carpenter\u4e8e1980\u5e74\u63d0\u51fa\uff0c\u53d1\u8868\u5728\u300aJournal of Verbal Learning and Verbal Behavior\u300b\u4e0a\u3002\u5b83\u4e0e\u4ed6\u4eec\u7684\u542c\u89c9\u5e7f\u5ea6\u7248\u672c\u4e00\u9053\uff0c\u88ab\u666e\u904d\u8ba4\u4e3a\u662f\u7b2c\u4e00\u4e2a\u590d\u6742\u5e7f\u5ea6\u4efb\u52a1\u3002",methods:"\u4ee5\u6b63\u5e38\u3001\u8e0f\u5b9e\u7684\u8282\u594f\u53bb\u8bfb\u6216\u5224\u65ad\u6bcf\u4e2a\u53e5\u5b50\uff0c\u522b\u4e3a\u4e86\u62a4\u4f4f\u5355\u8bcd\u5c31\u8349\u8349\u8d76\u8fc7\u52a0\u5de5\u90a3\u4e00\u6b65\uff0c\u56e0\u4e3a\u96be\u5ea6\u6070\u6070\u5728\u4e8e\u4e8c\u8005\u517c\u987e\u3002\u522b\u53ea\u662f\u673a\u68b0\u5730\u5faa\u73af\u5ff5\u90a3\u4e9b\u5355\u8bcd\uff1b\u628a\u6bcf\u4e2a\u8bcd\u8ddf\u5b83\u6240\u5728\u7684\u53e5\u5b50\u7ed1\u5728\u4e00\u8d77\uff0c\u6216\u8005\u5feb\u901f\u6784\u5efa\u4e00\u5e45\u5fc3\u8c61\u3001\u7f16\u4e2a\u5c0f\u6545\u4e8b\u628a\u5b83\u4eec\u4e32\u8d77\u6765\u3002\u53ea\u6709\u5f53\u4f60\u5728\u5f53\u524d\u957f\u5ea6\u4e0a\u7a33\u5b9a\u53ef\u9760\u65f6\uff0c\u624d\u628a\u96c6\u5408\u89c4\u6a21\u5f80\u4e0a\u52a0\u3002",duration:"\u77ed\u800c\u4e13\u6ce8\u7684\u5c0f\u6bb5\u6548\u679c\u6700\u597d\uff1a\u6bcf\u6b21\u7ea610\u523015\u5206\u949f\uff0c\u4e00\u5468\u51e0\u6b21\u3002\u8fd9\u7c7b\u4efb\u52a1\u5f88\u5feb\u5c31\u4f1a\u8ba9\u4eba\u75b2\u52b3\uff0c\u6240\u4ee5\u5f53\u4f60\u7684\u51c6\u786e\u7387\u5f00\u59cb\u4e0b\u6ed1\u65f6\u5c31\u505c\uff0c\u522b\u786c\u6491\u7740\u7d2f\u7740\u7ec3\u3002",research:"\u8bc1\u636e\u6700\u6709\u529b\u7684\u6070\u6070\u662f\u4f60\u80fd\u60f3\u5230\u7684\u90a3\u90e8\u5206\uff1a\u9605\u8bfb\u5e7f\u5ea6\u662f\u4e00\u9879\u624e\u5b9e\u3001\u7ecf\u8fc7\u5145\u5206\u9a8c\u8bc1\u7684\u5de5\u4f5c\u8bb0\u5fc6\u5bb9\u91cf\u6307\u6807\uff0c\u5206\u6570\u4e0e\u9605\u8bfb\u7406\u89e3\u76f8\u5173\u3002\u5b83\u65e0\u6cd5\u53ef\u9760\u505a\u5230\u7684\uff0c\u662f\u8ba9\u4f60\u6574\u4f53\u4e0a\u53d8\u5f97\u66f4\u806a\u660e\u3002\u5173\u4e8e\u5de5\u4f5c\u8bb0\u5fc6\u8bad\u7ec3\u7684\u5927\u578b\u5143\u5206\u6790\u548c\u5bf9\u7167\u7814\u7a76\uff08Melby-Lerv\xe5g\u7b49\u4eba\u3001Redick\u7b49\u4eba\uff09\u53d1\u73b0\uff0c\u6536\u76ca\u53ea\u505c\u7559\u5728\u88ab\u8bad\u7ec3\u7684\u4efb\u52a1\u9644\u8fd1\uff0c\u5e76\u4e0d\u4f1a\u8fc1\u79fb\u5230\u6d41\u4f53\u667a\u529b\u6216\u65e5\u5e38\u8ba4\u77e5\uff0c\u6240\u4ee5\u5bf9\u4efb\u4f55\u300c\u80fd\u63d0\u9ad8\u667a\u5546\u300d\u7684\u627f\u8bfa\u90fd\u8981\u4fdd\u6301\u8c28\u614e\u3002",rec:"\u7528\u5b83\u6765\u8bda\u5b9e\u5730\u78e8\u7ec3\u5e76\u8861\u91cf\u4f60\u7684\u5de5\u4f5c\u8bb0\u5fc6\uff0c\u800c\u4e0d\u662f\u628a\u5b83\u5f53\u6210\u63d0\u9ad8\u667a\u5546\u7684\u6377\u5f84\uff1b\u8bfb\u53e5\u5b50\u90a3\u4e00\u73af\u8981\u5f53\u771f\uff0c\u522b\u4e00\u626b\u800c\u8fc7\u3002",faq:[["\u8fd9\u8ddf\u5355\u7eaf\u80cc\u4e00\u4e32\u5355\u8bcd\u662f\u4e00\u56de\u4e8b\u5417\uff1f","\u4e0d\u662f\u3002\u5355\u7eaf\u80cc\u6e05\u5355\u53ea\u8003\u9a8c\u5b58\u50a8\uff1b\u800c\u300c\u9605\u8bfb\u5e7f\u5ea6\u300d\u903c\u7740\u4f60\u5728\u8bb0\u4f4f\u5355\u8bcd\u7684\u540c\u65f6\u5904\u7406\u6bcf\u4e2a\u53e5\u5b50\uff0c\u8fd9\u624d\u4f7f\u5b83\u6210\u4e3a\u8861\u91cf\u5de5\u4f5c\u8bb0\u5fc6\u7684\u6307\u6807\uff0c\u800c\u975e\u7b80\u5355\u7684\u77ed\u65f6\u8bb0\u5fc6\u3002"],["\u7ec3\u8fd9\u4e2a\u4f1a\u63d0\u9ad8\u6211\u7684\u667a\u5546\u3001\u8ba9\u6211\u6574\u4f53\u53d8\u806a\u660e\u5417\uff1f","\u8001\u5b9e\u8bf4\uff0c\u5927\u6982\u4e0d\u4f1a\u3002\u4f60\u4f1a\u5728\u8fd9\u4e2a\u4efb\u52a1\u548c\u7c7b\u4f3c\u7684\u5e7f\u5ea6\u4efb\u52a1\u4e0a\u53d8\u5f97\u66f4\u597d\uff0c\u4f46\u6700\u4e25\u8c28\u7684\u5bf9\u7167\u7814\u7a76\u8868\u660e\uff0c\u51e0\u4e4e\u6ca1\u6709\u4ec0\u4e48\u5411\u4e00\u822c\u667a\u529b\u6216\u65e0\u5173\u65e5\u5e38\u6280\u80fd\u7684\u8fc1\u79fb\u3002"],["\u6211\u8be5\u8bfb\u5feb\u70b9\u8ba9\u5b83\u66f4\u5bb9\u6613\u5417\uff1f","\u6c42\u5feb\u901a\u5e38\u9002\u5f97\u5176\u53cd\u3002\u6311\u6218\u5728\u4e8e\u300c\u8bfb\u300d\u548c\u300c\u8bb0\u300d\u7684\u7ed3\u5408\uff0c\u6240\u4ee5\u8bf7\u4ee5\u771f\u5b9e\u7684\u8282\u594f\u9605\u8bfb\uff0c\u628a\u529b\u6c14\u82b1\u5728\u628a\u6bcf\u4e2a\u8bcd\u8ddf\u5b83\u7684\u53e5\u5b50\u8054\u7cfb\u8d77\u6765\uff0c\u800c\u4e0d\u662f\u4e00\u8def\u72c2\u5954\u3002"]],variants:"\u8fd1\u4eb2\u7248\u672c\u4f1a\u66ff\u6362\u52a0\u5de5\u4efb\u52a1\uff1a\u8fd0\u7b97\u5e7f\u5ea6\u628a\u5355\u8bcd\u914d\u4e0a\u6570\u5b66\u9898\uff0c\u5bf9\u79f0\u5e7f\u5ea6\u7528\u89c6\u89c9\u5224\u65ad\uff0c\u542c\u89c9\u5e7f\u5ea6\u5219\u8ba9\u4f60\u542c\u53e5\u5b50\u800c\u975e\u8bfb\u53e5\u5b50\u3002\u5404\u7248\u672c\u8fd8\u5728\u4ee5\u4e0b\u65b9\u9762\u6709\u522b\uff1a\u662f\u5426\u8981\u6309\u987a\u5e8f\u56de\u5fc6\u5355\u8bcd\u3001\u53e5\u5b50\u662f\u5426\u5fc5\u987b\u5224\u65ad\u771f\u5047\u3001\u4ee5\u53ca\u96c6\u5408\u89c4\u6a21\u5982\u4f55\u6392\u5e03\u3002"}},rmet:{ru:{about:"\u0412\u0430\u043c \u043f\u043e\u043a\u0430\u0437\u044b\u0432\u0430\u044e\u0442 \u0444\u043e\u0442\u043e\u0433\u0440\u0430\u0444\u0438\u044e, \u043e\u0431\u0440\u0435\u0437\u0430\u043d\u043d\u0443\u044e \u0434\u043e \u043e\u0434\u043d\u043e\u0439 \u043e\u0431\u043b\u0430\u0441\u0442\u0438 \u0433\u043b\u0430\u0437, \u0430 \u0432\u043e\u043a\u0440\u0443\u0433 \u043d\u0435\u0451 \u0447\u0435\u0442\u044b\u0440\u0435 \u0441\u043b\u043e\u0432\u0430-\u0441\u043e\u0441\u0442\u043e\u044f\u043d\u0438\u044f (\u043d\u0430\u043f\u0440\u0438\u043c\u0435\u0440: \u0440\u0435\u0432\u043d\u0443\u0435\u0442, \u0432 \u043f\u0430\u043d\u0438\u043a\u0435, \u0432\u044b\u0441\u043e\u043a\u043e\u043c\u0435\u0440\u0435\u043d, \u0441 \u043d\u0435\u043d\u0430\u0432\u0438\u0441\u0442\u044c\u044e). \u041d\u0443\u0436\u043d\u043e \u0432\u044b\u0431\u0440\u0430\u0442\u044c \u043e\u0434\u043d\u043e \u0441\u043b\u043e\u0432\u043e, \u043a\u043e\u0442\u043e\u0440\u043e\u0435 \u043b\u0443\u0447\u0448\u0435 \u0432\u0441\u0435\u0433\u043e \u043f\u0435\u0440\u0435\u0434\u0430\u0451\u0442, \u0447\u0442\u043e \u0447\u0435\u043b\u043e\u0432\u0435\u043a \u0434\u0443\u043c\u0430\u0435\u0442 \u0438\u043b\u0438 \u0447\u0443\u0432\u0441\u0442\u0432\u0443\u0435\u0442. \u0421\u0442\u0430\u043d\u0434\u0430\u0440\u0442\u043d\u044b\u0439 \u043d\u0430\u0431\u043e\u0440 \u2014 36 \u0444\u043e\u0442\u043e\u0433\u0440\u0430\u0444\u0438\u0439.",benefit:"\u0422\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u0441\u043e\u0446\u0438\u0430\u043b\u044c\u043d\u043e\u0435 \u043f\u043e\u0437\u043d\u0430\u043d\u0438\u0435: \u0443\u043c\u0435\u043d\u0438\u0435 \u0441\u0447\u0438\u0442\u044b\u0432\u0430\u0442\u044c \u0442\u043e\u043d\u043a\u0438\u0435 \u044d\u043c\u043e\u0446\u0438\u0438 \u0438 \u043d\u0430\u043c\u0435\u0440\u0435\u043d\u0438\u044f \u043f\u043e \u043e\u0434\u043d\u0438\u043c \u0433\u043b\u0430\u0437\u0430\u043c, \u0430 \u0437\u0430\u043e\u0434\u043d\u043e \u0441\u043b\u043e\u0432\u0430\u0440\u044c \u0447\u0443\u0432\u0441\u0442\u0432, \u0431\u0435\u0437 \u043a\u043e\u0442\u043e\u0440\u043e\u0433\u043e \u044d\u0442\u0438 \u0441\u043e\u0441\u0442\u043e\u044f\u043d\u0438\u044f \u043d\u0435 \u043d\u0430\u0437\u0432\u0430\u0442\u044c \u0442\u043e\u0447\u043d\u043e. \u041f\u043e \u0441\u0443\u0442\u0438 \u0432\u044b \u043f\u0440\u043e\u043a\u0430\u0447\u0438\u0432\u0430\u0435\u0442\u0435 \u0431\u044b\u0441\u0442\u0440\u043e\u0435 \u0438 \u0434\u0435\u0442\u0430\u043b\u044c\u043d\u043e\u0435 \u0440\u0430\u0441\u043f\u043e\u0437\u043d\u0430\u0432\u0430\u043d\u0438\u0435 \u043c\u0438\u043c\u0438\u0447\u0435\u0441\u043a\u0438\u0445 \u0441\u0438\u0433\u043d\u0430\u043b\u043e\u0432.",history:"\u0421\u043d\u0430\u0447\u0430\u043b\u0430 \u044d\u0442\u043e \u0431\u044b\u043b \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u044c\u0441\u043a\u0438\u0439 \u0438\u043d\u0441\u0442\u0440\u0443\u043c\u0435\u043d\u0442 \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u0438, \u0430 \u043d\u0435 \u0438\u0433\u0440\u0430. \u0413\u0440\u0443\u043f\u043f\u0430 \u0421\u0430\u0439\u043c\u043e\u043d\u0430 \u0411\u0430\u0440\u043e\u043d\u0430-\u041a\u043e\u044d\u043d\u0430 \u0432\u044b\u043f\u0443\u0441\u0442\u0438\u043b\u0430 \u043f\u0435\u0440\u0432\u0443\u044e \u0432\u0435\u0440\u0441\u0438\u044e \xab\u0442\u0435\u0441\u0442\u0430 \u043f\u043e \u0433\u043b\u0430\u0437\u0430\u043c\xbb \u0432 1997 \u0433\u043e\u0434\u0443 \u043a\u0430\u043a \u043f\u0440\u043e\u0434\u0432\u0438\u043d\u0443\u0442\u0443\u044e \u043c\u0435\u0442\u043e\u0434\u0438\u043a\u0443 \u043e\u0446\u0435\u043d\u043a\u0438 \u043c\u043e\u0434\u0435\u043b\u0438 \u043f\u0441\u0438\u0445\u0438\u0447\u0435\u0441\u043a\u043e\u0433\u043e \u0443 \u0432\u0437\u0440\u043e\u0441\u043b\u044b\u0445, \u0430 \u0432 2001-\u043c, \u043f\u043e\u0441\u043b\u0435 \u043a\u0440\u0438\u0442\u0438\u043a\u0438, \u0432\u044b\u0448\u043b\u0430 \u043f\u0435\u0440\u0435\u0440\u0430\u0431\u043e\u0442\u0430\u043d\u043d\u0430\u044f \u0432\u0435\u0440\u0441\u0438\u044f. \u041c\u0435\u0442\u043e\u0434\u0438\u043a\u0430 \u0431\u044b\u0441\u0442\u0440\u043e \u0440\u0430\u0437\u043e\u0448\u043b\u0430\u0441\u044c: \u0435\u0451 \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u043b\u0438 \u0431\u043e\u043b\u0435\u0435 \u0447\u0435\u043c \u0432 250 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u044f\u0445 \u0438 \u043f\u0435\u0440\u0435\u0432\u0435\u043b\u0438 \u043d\u0430 \u0434\u0435\u0441\u044f\u0442\u043a\u0438 \u044f\u0437\u044b\u043a\u043e\u0432, \u0430 \u0444\u043e\u0440\u043c\u0430\u0442 \xab\u0433\u043b\u0430\u0437\u0430 \u043f\u043b\u044e\u0441 \u0447\u0435\u0442\u044b\u0440\u0435 \u0441\u043b\u043e\u0432\u0430\xbb \u043f\u043e\u0437\u0436\u0435 \u043f\u0440\u0435\u0432\u0440\u0430\u0442\u0438\u043b\u0438 \u0432 \u043f\u043e\u043f\u0443\u043b\u044f\u0440\u043d\u044b\u0435 \u043e\u043d\u043b\u0430\u0439\u043d-\u0442\u0435\u0441\u0442\u044b \u0438 \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u044f \u0434\u043b\u044f \u043c\u043e\u0437\u0433\u0430.",creator:"\u0421\u0430\u0439\u043c\u043e\u043d \u0411\u0430\u0440\u043e\u043d-\u041a\u043e\u044d\u043d \u0438 \u0435\u0433\u043e \u043a\u043e\u043b\u043b\u0435\u0433\u0438 \u0438\u0437 \u041a\u0435\u043c\u0431\u0440\u0438\u0434\u0436\u0441\u043a\u043e\u0433\u043e \u0443\u043d\u0438\u0432\u0435\u0440\u0441\u0438\u0442\u0435\u0442\u0430. \u0418\u0441\u0445\u043e\u0434\u043d\u044b\u0439 \u0442\u0435\u0441\u0442 \u2014 1997 \u0433\u043e\u0434\u0430; \u0448\u0438\u0440\u043e\u043a\u043e \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0435\u043c\u0443\u044e \u043f\u0435\u0440\u0435\u0440\u0430\u0431\u043e\u0442\u0430\u043d\u043d\u0443\u044e \u0432\u0435\u0440\u0441\u0438\u044e (\u0411\u0430\u0440\u043e\u043d-\u041a\u043e\u044d\u043d, \u0423\u0438\u043b\u0440\u0430\u0439\u0442, \u0425\u0438\u043b\u043b, \u0420\u0430\u0441\u0442\u0435 \u0438 \u041f\u043b\u0430\u043c\u0431) \u043e\u043f\u0443\u0431\u043b\u0438\u043a\u043e\u0432\u0430\u043b\u0438 \u0432 2001 \u0433\u043e\u0434\u0443 \u0432 Journal of Child Psychology and Psychiatry.",methods:"\u0421\u043d\u0430\u0447\u0430\u043b\u0430 \u0441\u043c\u043e\u0442\u0440\u0438\u0442\u0435 \u043d\u0430 \u0433\u043b\u0430\u0437\u0430 \u0438 \u0441\u043e\u0441\u0442\u0430\u0432\u044c\u0442\u0435 \u0432\u043f\u0435\u0447\u0430\u0442\u043b\u0435\u043d\u0438\u0435, \u0438 \u0442\u043e\u043b\u044c\u043a\u043e \u043f\u043e\u0442\u043e\u043c \u0447\u0438\u0442\u0430\u0439\u0442\u0435 \u0441\u043b\u043e\u0432\u0430, \u0447\u0442\u043e\u0431\u044b \u043f\u043e\u0434\u043f\u0438\u0441\u0438 \u043d\u0435 \u0441\u0431\u0438\u0432\u0430\u043b\u0438 \u0432\u0430\u0441. \u0426\u0435\u043f\u043b\u044f\u0439\u0442\u0435\u0441\u044c \u0437\u0430 \u043a\u043e\u043d\u043a\u0440\u0435\u0442\u043d\u044b\u0435 \u043f\u0440\u0438\u0437\u043d\u0430\u043a\u0438: \u043d\u0430\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u043e\u0442\u043a\u0440\u044b\u0442\u044b \u0432\u0435\u043a\u0438, \u043f\u043e\u0434 \u043a\u0430\u043a\u0438\u043c \u0443\u0433\u043b\u043e\u043c \u0431\u0440\u043e\u0432\u0438, \u043a\u0443\u0434\u0430 \u043d\u0430\u043f\u0440\u0430\u0432\u043b\u0435\u043d \u0432\u0437\u0433\u043b\u044f\u0434, \u0438 \u043e\u0442\u0441\u0435\u043a\u0430\u0439\u0442\u0435 \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u044b, \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u044f\u0432\u043d\u043e \u043d\u0435 \u043f\u043e\u0434\u0445\u043e\u0434\u044f\u0442. \u041e\u0448\u0438\u0431\u043b\u0438\u0441\u044c \u2014 \u043e\u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u0435\u0441\u044c \u0438 \u0432\u044b\u0443\u0447\u0438\u0442\u0435 \u0441\u043b\u043e\u0432\u043e: \u0437\u043d\u0430\u0447\u0438\u0442\u0435\u043b\u044c\u043d\u0430\u044f \u0447\u0430\u0441\u0442\u044c \u043f\u0440\u043e\u043c\u0430\u0445\u043e\u0432 \u044d\u0442\u043e \u043f\u0440\u043e\u0431\u0435\u043b \u0432 \u0441\u043b\u043e\u0432\u0430\u0440\u0435, \u0430 \u043d\u0435 \u0432 \u0432\u043e\u0441\u043f\u0440\u0438\u044f\u0442\u0438\u0438, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u0431\u043e\u0433\u0430\u0442\u044b\u0439 \u0441\u043b\u043e\u0432\u0430\u0440\u044c \u0447\u0443\u0432\u0441\u0442\u0432 \u043d\u0430\u043f\u0440\u044f\u043c\u0443\u044e \u043f\u043e\u0434\u043d\u0438\u043c\u0430\u0435\u0442 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442.",duration:"\u041b\u0443\u0447\u0448\u0435 \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u043c\u0438 \u043f\u043e\u0434\u0445\u043e\u0434\u0430\u043c\u0438: \u043e\u0434\u0438\u043d \u043f\u0440\u043e\u0445\u043e\u0434 \u0438\u0437 36 \u043b\u0438\u0446 \u0437\u0430\u043d\u0438\u043c\u0430\u0435\u0442 \u0432\u0441\u0435\u0433\u043e \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u043c\u0438\u043d\u0443\u0442. \u0414\u0432\u0443\u0445-\u0442\u0440\u0451\u0445 \u0441\u043e\u0441\u0440\u0435\u0434\u043e\u0442\u043e\u0447\u0435\u043d\u043d\u044b\u0445 \u043f\u043e\u0434\u0445\u043e\u0434\u043e\u0432 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e \u0434\u043e\u0441\u0442\u0430\u0442\u043e\u0447\u043d\u043e; \u0440\u0430\u0437\u0431\u043e\u0440 \u0441\u0432\u043e\u0438\u0445 \u043e\u0448\u0438\u0431\u043e\u043a \u0432\u0430\u0436\u043d\u0435\u0435, \u0447\u0435\u043c \u043a\u043e\u043b\u0438\u0447\u0435\u0441\u0442\u0432\u043e \u043f\u043e\u0432\u0442\u043e\u0440\u043e\u0432.",research:"\u0427\u0442\u043e \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043d\u043e \u0442\u0432\u0451\u0440\u0434\u043e: \u0442\u0435\u0441\u0442 \u043d\u0430\u0434\u0451\u0436\u043d\u043e \u0440\u0430\u0437\u043b\u0438\u0447\u0430\u0435\u0442 \u0433\u0440\u0443\u043f\u043f\u044b \u0432 \u0441\u0440\u0435\u0434\u043d\u0435\u043c \u2014 \u0432\u0437\u0440\u043e\u0441\u043b\u044b\u0435 \u0441 \u0430\u0443\u0442\u0438\u0437\u043c\u043e\u043c \u043e\u0431\u044b\u0447\u043d\u043e \u043d\u0430\u0431\u0438\u0440\u0430\u044e\u0442 \u043c\u0435\u043d\u044c\u0448\u0435, \u0430 \u043c\u0435\u0442\u0430-\u0430\u043d\u0430\u043b\u0438\u0437\u044b \u0444\u0438\u043a\u0441\u0438\u0440\u0443\u044e\u0442 \u043d\u0435\u0431\u043e\u043b\u044c\u0448\u043e\u0435 \u043f\u0440\u0435\u0438\u043c\u0443\u0449\u0435\u0441\u0442\u0432\u043e \u0436\u0435\u043d\u0449\u0438\u043d; \u0441 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u043e\u0439 \u0432\u044b \u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u0435\u0441\u044c \u043b\u0443\u0447\u0448\u0435 \u0432 \u0441\u0430\u043c\u043e\u043c \u0437\u0430\u0434\u0430\u043d\u0438\u0438. \u0427\u0442\u043e \u0448\u0430\u0442\u043a\u043e: \u0432\u0441\u0451 \u0431\u043e\u043b\u044c\u0448\u0435 \u0440\u0430\u0431\u043e\u0442 \u0441\u0442\u0430\u0432\u0438\u0442 \u043f\u043e\u0434 \u0432\u043e\u043f\u0440\u043e\u0441, \u0447\u0442\u043e \u0438\u043c\u0435\u043d\u043d\u043e \u043e\u043d \u0438\u0437\u043c\u0435\u0440\u044f\u0435\u0442, \u0438 \u0434\u043e\u043a\u0430\u0437\u044b\u0432\u0430\u0435\u0442, \u0447\u0442\u043e \u043e\u043d \u0441\u043a\u043e\u0440\u0435\u0435 \u043e\u0442\u0440\u0430\u0436\u0430\u0435\u0442 \u0437\u043d\u0430\u043d\u0438\u0435 \u0441\u043b\u043e\u0432-\u044d\u043c\u043e\u0446\u0438\u0439 \u0438 \u0443\u0437\u043d\u0430\u0432\u0430\u043d\u0438\u0435, \u0447\u0435\u043c \u043d\u0430\u0441\u0442\u043e\u044f\u0449\u0435\u0435 \xab\u0447\u0442\u0435\u043d\u0438\u0435 \u043c\u044b\u0441\u043b\u0435\u0439\xbb; \u043e\u0442\u043c\u0435\u0447\u0430\u044e\u0442 \u0441\u043b\u0430\u0431\u0443\u044e \u0432\u043d\u0443\u0442\u0440\u0435\u043d\u043d\u044e\u044e \u0441\u043e\u0433\u043b\u0430\u0441\u043e\u0432\u0430\u043d\u043d\u043e\u0441\u0442\u044c \u0438 \u043f\u043b\u043e\u0445\u0443\u044e \u0444\u0430\u043a\u0442\u043e\u0440\u043d\u0443\u044e \u0441\u0442\u0440\u0443\u043a\u0442\u0443\u0440\u0443, \u0430 \u0447\u0430\u0441\u0442\u044c \u043f\u0443\u043d\u043a\u0442\u043e\u0432 \u0440\u0430\u0431\u043e\u0442\u0430\u0435\u0442 \u043d\u0435\u043a\u043e\u0440\u0440\u0435\u043a\u0442\u043d\u043e. \u0421\u0432\u044f\u0437\u044c \u0441 \u0441\u0430\u043c\u043e\u043e\u0446\u0435\u043d\u043a\u043e\u0439 \u044d\u043c\u043f\u0430\u0442\u0438\u0438 \u043d\u0435\u0443\u0441\u0442\u043e\u0439\u0447\u0438\u0432\u0430, \u0430 \u0438\u0437\u0432\u0435\u0441\u0442\u043d\u044b\u0439 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442 \u043f\u0440\u043e \u0442\u043e, \u0447\u0442\u043e \u043e\u043a\u0441\u0438\u0442\u043e\u0446\u0438\u043d \u043f\u043e\u0432\u044b\u0448\u0430\u0435\u0442 \u0431\u0430\u043b\u043b\u044b, \u043f\u043b\u043e\u0445\u043e \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0438\u0442\u0441\u044f. \u0417\u0430\u044f\u0432\u043b\u0435\u043d\u0438\u044f, \u0431\u0443\u0434\u0442\u043e \u043e\u043d \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u0448\u0438\u0440\u043e\u043a\u0438\u0435 \u0441\u043e\u0446\u0438\u0430\u043b\u044c\u043d\u044b\u0435 \u043d\u0430\u0432\u044b\u043a\u0438 \u0438\u043b\u0438 \u044d\u043c\u043f\u0430\u0442\u0438\u044e \u0432 \u0436\u0438\u0437\u043d\u0438, \u0441\u0447\u0438\u0442\u0430\u0439\u0442\u0435 \u043d\u0435\u0434\u043e\u043a\u0430\u0437\u0430\u043d\u043d\u044b\u043c\u0438.",rec:"\u041a\u0430\u0436\u0434\u044b\u0439 \u043f\u0440\u043e\u043c\u0430\u0445 \u0432\u043e\u0441\u043f\u0440\u0438\u043d\u0438\u043c\u0430\u0439\u0442\u0435 \u043a\u0430\u043a \u0443\u0440\u043e\u043a \u0441\u043b\u043e\u0432\u0430\u0440\u044f, \u0430 \u043d\u0435 \u043f\u0440\u043e\u0441\u0442\u043e \u043a\u0430\u043a \u043d\u0435\u0432\u0435\u0440\u043d\u044b\u0439 \u043a\u043b\u0438\u043a, \u0438 \u043e\u0431\u044f\u0437\u0430\u0442\u0435\u043b\u044c\u043d\u043e \u0441\u043c\u043e\u0442\u0440\u0438\u0442\u0435 \u0442\u043e\u0447\u043d\u043e\u0435 \u0437\u043d\u0430\u0447\u0435\u043d\u0438\u0435 \u0441\u043b\u043e\u0432\u0430, \u043f\u0440\u0435\u0436\u0434\u0435 \u0447\u0435\u043c \u0438\u0434\u0442\u0438 \u0434\u0430\u043b\u044c\u0448\u0435.",faq:[["\u041d\u0438\u0437\u043a\u0438\u0439 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442 \u2014 \u043f\u0440\u0438\u0437\u043d\u0430\u043a \u0430\u0443\u0442\u0438\u0437\u043c\u0430?","\u041d\u0435\u0442. \u041c\u0435\u0442\u043e\u0434\u0438\u043a\u0443 \u0441\u043e\u0437\u0434\u0430\u0432\u0430\u043b\u0438 \u043a\u0430\u043a \u0433\u0440\u0443\u043f\u043f\u043e\u0432\u0443\u044e \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u044c\u0441\u043a\u0443\u044e \u043c\u0435\u0440\u0443, \u0430 \u043d\u0435 \u043a\u0430\u043a \u0434\u0438\u0430\u0433\u043d\u043e\u0441\u0442\u0438\u043a\u0443. \u0421\u0440\u0435\u0434\u0438 \u043b\u044e\u0434\u0435\u0439 \u0431\u0435\u0437 \u0430\u0443\u0442\u0438\u0437\u043c\u0430 \u0431\u0430\u043b\u043b\u044b \u0441\u0438\u043b\u044c\u043d\u043e \u0440\u0430\u0437\u043b\u0438\u0447\u0430\u044e\u0442\u0441\u044f, \u0438 \u0441\u0430\u043c \u043f\u043e \u0441\u0435\u0431\u0435 \u043d\u0438\u0437\u043a\u0438\u0439 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442 \u043f\u043e\u0447\u0442\u0438 \u043d\u0438\u0447\u0435\u0433\u043e \u043d\u0435 \u0433\u043e\u0432\u043e\u0440\u0438\u0442 \u043e \u043a\u043e\u043d\u043a\u0440\u0435\u0442\u043d\u043e\u043c \u0447\u0435\u043b\u043e\u0432\u0435\u043a\u0435."],["\u0415\u0441\u043b\u0438 \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u0430\u0442\u044c\u0441\u044f, \u044f \u043d\u0430\u0447\u043d\u0443 \u043b\u0443\u0447\u0448\u0435 \u043f\u043e\u043d\u0438\u043c\u0430\u0442\u044c \u043b\u044e\u0434\u0435\u0439 \u0432 \u0436\u0438\u0437\u043d\u0438?","\u0412 \u043e\u0441\u043d\u043e\u0432\u043d\u043e\u043c \u0432\u044b \u0441\u0442\u0430\u043d\u0435\u0442\u0435 \u043b\u0443\u0447\u0448\u0435 \u0438\u043c\u0435\u043d\u043d\u043e \u0432 \u044d\u0442\u043e\u043c \u0437\u0430\u0434\u0430\u043d\u0438\u0438. \u0421\u043a\u043e\u0440\u0435\u0435 \u0432\u0441\u0435\u0433\u043e, \u0432\u044b \u043d\u0430\u0443\u0447\u0438\u0442\u0435\u0441\u044c \u0442\u043e\u0447\u043d\u0435\u0435 \u0432\u044b\u0431\u0438\u0440\u0430\u0442\u044c \u043d\u0443\u0436\u043d\u043e\u0435 \u0441\u043b\u043e\u0432\u043e \u043f\u043e \u0433\u043b\u0430\u0437\u0430\u043c, \u043d\u043e \u0434\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432, \u0447\u0442\u043e \u044d\u0442\u043e \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0438\u0442\u0441\u044f \u043d\u0430 \u043f\u043e\u0432\u0441\u0435\u0434\u043d\u0435\u0432\u043d\u043e\u0435 \u043e\u0431\u0449\u0435\u043d\u0438\u0435 \u0438\u043b\u0438 \u044d\u043c\u043f\u0430\u0442\u0438\u044e, \u043c\u0430\u043b\u043e, \u0438 \u043e\u043d\u0438 \u0441\u043f\u043e\u0440\u043d\u044b."],["\u041f\u043e\u0447\u0435\u043c\u0443 \u043d\u0435\u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u043e\u0442\u0432\u0435\u0442\u044b \u0442\u0430\u043a\u0438\u0435 \u0442\u0440\u0443\u0434\u043d\u044b\u0435, \u0445\u043e\u0442\u044f \u0433\u043b\u0430\u0437\u0430 \u0432\u0440\u043e\u0434\u0435 \u0431\u044b \u043f\u043e\u043d\u044f\u0442\u043d\u044b?","\u0427\u0430\u0441\u0442\u043e \u0443\u0437\u043a\u043e\u0435 \u043c\u0435\u0441\u0442\u043e \u2014 \u0441\u043b\u043e\u0432\u0430, \u0430 \u043d\u0435 \u043b\u0438\u0446\u043e. \u0421\u0440\u0435\u0434\u0438 \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u043e\u0432 \u0435\u0441\u0442\u044c \u0442\u043e\u043d\u043a\u0438\u0435 \u0438 \u0440\u0435\u0434\u043a\u0438\u0435 \u0442\u0435\u0440\u043c\u0438\u043d\u044b, \u043f\u043e\u044d\u0442\u043e\u043c\u0443, \u0435\u0441\u043b\u0438 \u0432\u044b \u043d\u0435 \u0437\u043d\u0430\u0435\u0442\u0435 \u0442\u043e\u0447\u043d\u043e\u0433\u043e \u0437\u043d\u0430\u0447\u0435\u043d\u0438\u044f \u0441\u043b\u043e\u0432\u0430 \u0432\u0440\u043e\u0434\u0435 \xab\u0437\u0430\u0434\u0443\u043c\u0447\u0438\u0432\u044b\u0439\xbb \u0438\u043b\u0438 \xab\u0432\u0441\u0442\u0440\u0435\u0432\u043e\u0436\u0435\u043d\u043d\u044b\u0439\xbb, \u043c\u043e\u0436\u043d\u043e \u0432\u0435\u0440\u043d\u043e \u043f\u0440\u043e\u0447\u0438\u0442\u0430\u0442\u044c \u044d\u043c\u043e\u0446\u0438\u044e \u0438 \u0432\u0441\u0451 \u0440\u0430\u0432\u043d\u043e \u043e\u0448\u0438\u0431\u0438\u0442\u044c\u0441\u044f."]],variants:"\u0415\u0441\u0442\u044c \u0434\u0435\u0442\u0441\u043a\u0430\u044f \u0432\u0435\u0440\u0441\u0438\u044f \u0441 \u0431\u043e\u043b\u0435\u0435 \u043f\u0440\u043e\u0441\u0442\u044b\u043c\u0438 \u0441\u043b\u043e\u0432\u0430\u043c\u0438 \u0438 \u043f\u0435\u0440\u0435\u0432\u043e\u0434\u044b \u043d\u0430 \u0440\u0430\u0437\u043d\u044b\u0435 \u044f\u0437\u044b\u043a\u0438 \u0441\u043e \u0441\u0432\u043e\u0438\u043c\u0438 \u0432\u044b\u0432\u0435\u0440\u0435\u043d\u043d\u044b\u043c\u0438 \u043a\u043b\u044e\u0447\u0430\u043c\u0438 \u043e\u0442\u0432\u0435\u0442\u043e\u0432. \u0420\u043e\u0434\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0435 \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u044f \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u044e\u0442 \u0446\u0435\u043b\u044b\u0435 \u043b\u0438\u0446\u0430 \u0432\u043c\u0435\u0441\u0442\u043e \u043e\u0434\u043d\u0438\u0445 \u0433\u043b\u0430\u0437, \u0432\u0438\u0434\u0435\u043e\u0440\u043e\u043b\u0438\u043a\u0438 \u0441 \u0434\u0438\u043d\u0430\u043c\u0438\u0447\u043d\u043e\u0439 \u043c\u0438\u043c\u0438\u043a\u043e\u0439 \u0438\u043b\u0438 \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u043a\u0438 \u043f\u043e \u0433\u043e\u043b\u043e\u0441\u0443 \u0438 \u043f\u043e\u0437\u0435, \u0430 \u043d\u0435\u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u043f\u0440\u0438\u043b\u043e\u0436\u0435\u043d\u0438\u044f \u0434\u043e\u0431\u0430\u0432\u043b\u044f\u044e\u0442 \u0442\u0430\u0439\u043c\u0435\u0440 \u0438 \u043e\u0431\u0440\u0430\u0442\u043d\u0443\u044e \u0441\u0432\u044f\u0437\u044c \u043f\u043e\u0441\u043b\u0435 \u043a\u0430\u0436\u0434\u043e\u0433\u043e \u043f\u0443\u043d\u043a\u0442\u0430."},en:{about:"You are shown a close-up photo cropped to just the eye region of a face, with four emotion or mental-state words around it (for example: jealous, panicked, arrogant, hateful). Your job is to pick the single word that best describes what the person is thinking or feeling. The standard set runs 36 photos.",benefit:"It trains social cognition: reading subtle emotional and mental states from the eyes alone, plus the emotion vocabulary you need to label those states precisely. In practical terms you are exercising rapid, fine-grained facial-cue interpretation.",history:"It began as a psychology research instrument, not a game. Simon Baron-Cohen's group introduced the original 'Eyes Test' in 1997 as an advanced theory-of-mind measure for adults, then released a revised version in 2001 after the first one was criticised. It spread fast, has been used in well over 250 studies and translated into many languages, and the eyes-and-words format was later adapted into popular online quizzes and brain-training drills.",creator:"Simon Baron-Cohen and colleagues at the University of Cambridge. The original test is from 1997; the widely used revised version (Baron-Cohen, Wheelwright, Hill, Raste and Plumb) was published in 2001 in the Journal of Child Psychology and Psychiatry.",methods:"Look at the eyes first and form an impression before you read the four words, so the labels do not bias you. Pay attention to concrete cues, the openness of the lids, the angle of the brows, the direction of gaze, and rule out the options that clearly do not fit. When you miss one, stop and learn the word: many errors are vocabulary gaps, not perception gaps, so building a richer feelings vocabulary directly raises your score.",duration:"Short sessions work best: one pass of 36 faces takes only a few minutes. Two or three focused sessions a week is plenty; reviewing the items you got wrong matters more than sheer volume.",research:"What is solid: the test reliably separates groups on average, autistic adults tend to score lower than non-autistic adults, and meta-analyses report a small female advantage. With practice you also get better at the task itself. What is shaky: a growing body of work questions what it actually measures, arguing it may tap emotion-word knowledge and recognition more than genuine 'mind-reading', and reports weak internal consistency and a poor factor structure, with some items behaving badly. Links to self-reported empathy are inconsistent, and the well-known finding that oxytocin boosts Eyes-Test scores has struggled to replicate. Treat claims that it trains broad real-world social skill or empathy as unproven.",rec:"Treat every miss as a vocabulary lesson, not just a wrong guess, and look up the exact word before moving on.",faq:[["Is a low score a sign of autism?","No. It was built as a group-level research measure, not a diagnostic tool. Scores vary widely among people without autism, and on its own a low score tells you very little about any individual."],["Will practising it make me better at reading people in real life?","Mostly it makes you better at this specific task. You will likely improve at picking the labelled word from the eyes, but evidence that this transfers to everyday social skill or empathy is weak and contested."],["Why are some answers so hard even when the eyes look obvious?","Often the bottleneck is the words, not the face. The options include subtle, uncommon terms, so if you do not precisely know a word like 'contemplative' or 'apprehensive' you can read the emotion correctly and still choose wrong."]],variants:"There is a child version with simpler wording, and translated editions in many languages with locally validated answer keys. Related drills use whole faces instead of just the eyes, dynamic video clips of expressions, or voice and body-posture cues, and some apps add a timer or feedback after each item."},es:{about:"Se te muestra una foto en primer plano recortada a solo la zona de los ojos de un rostro, con cuatro palabras de emoci\xf3n o estado mental alrededor (por ejemplo: celoso, aterrado, arrogante, lleno de odio). Tu tarea es elegir la \xfanica palabra que mejor describe lo que esa persona est\xe1 pensando o sintiendo. El conjunto est\xe1ndar consta de 36 fotos.",benefit:"Entrena la cognici\xf3n social: leer estados emocionales y mentales sutiles solo a partir de los ojos, adem\xe1s del vocabulario emocional que necesitas para nombrar esos estados con precisi\xf3n. En t\xe9rminos pr\xe1cticos, ejercitas la interpretaci\xf3n r\xe1pida y fina de las se\xf1ales faciales.",history:"Empez\xf3 como instrumento de investigaci\xf3n psicol\xf3gica, no como juego. El grupo de Simon Baron-Cohen present\xf3 el 'Test de la Mirada' original en 1997 como una medida avanzada de teor\xeda de la mente para adultos, y luego public\xf3 una versi\xf3n revisada en 2001 despu\xe9s de que la primera fuera criticada. Se difundi\xf3 r\xe1pido, se ha usado en bastante m\xe1s de 250 estudios y se ha traducido a muchos idiomas, y el formato de ojos y palabras se adapt\xf3 m\xe1s tarde a populares cuestionarios en l\xednea y ejercicios de entrenamiento cerebral.",creator:"Simon Baron-Cohen y colaboradores de la Universidad de Cambridge. El test original es de 1997; la versi\xf3n revisada de uso extendido (Baron-Cohen, Wheelwright, Hill, Raste y Plumb) se public\xf3 en 2001 en el Journal of Child Psychology and Psychiatry.",methods:"Mira primero los ojos y f\xf3rmate una impresi\xf3n antes de leer las cuatro palabras, para que las etiquetas no te condicionen. Atiende a se\xf1ales concretas: la apertura de los p\xe1rpados, el \xe1ngulo de las cejas, la direcci\xf3n de la mirada, y descarta las opciones que claramente no encajan. Cuando falles una, detente y aprende la palabra: muchos errores son lagunas de vocabulario, no de percepci\xf3n, as\xed que ampliar tu vocabulario de emociones eleva directamente tu puntuaci\xf3n.",duration:"Lo mejor son las sesiones cortas: una pasada de 36 rostros lleva solo unos minutos. Dos o tres sesiones concentradas por semana son de sobra; repasar los \xedtems que fallaste importa m\xe1s que el puro volumen.",research:"Lo s\xf3lido: el test separa de forma fiable a los grupos en promedio, los adultos autistas tienden a puntuar m\xe1s bajo que los no autistas, y los metaan\xe1lisis informan de una peque\xf1a ventaja femenina. Con la pr\xe1ctica tambi\xe9n mejoras en la propia tarea. Lo dudoso: un cuerpo creciente de trabajos cuestiona qu\xe9 mide en realidad, argumentando que puede apoyarse m\xe1s en el conocimiento y el reconocimiento de palabras de emoci\xf3n que en una genuina 'lectura de la mente', e informa de una consistencia interna d\xe9bil y una estructura factorial pobre, con algunos \xedtems que se comportan mal. Los v\xednculos con la empat\xeda autoinformada son inconsistentes, y el conocido hallazgo de que la oxitocina mejora las puntuaciones del Test de la Mirada ha tenido dificultades para replicarse. Toma como no demostradas las afirmaciones de que entrena una amplia habilidad social o empat\xeda en el mundo real.",rec:"Trata cada fallo como una lecci\xf3n de vocabulario, no solo como una respuesta err\xf3nea, y busca la palabra exacta antes de continuar.",faq:[["\xbfUna puntuaci\xf3n baja es se\xf1al de autismo?","No. Se construy\xf3 como una medida de investigaci\xf3n a nivel de grupo, no como herramienta diagn\xf3stica. Las puntuaciones var\xedan mucho entre personas sin autismo y, por s\xed sola, una puntuaci\xf3n baja dice muy poco sobre cualquier individuo."],["\xbfPracticarlo me har\xe1 mejor leyendo a la gente en la vida real?","Sobre todo te hace mejor en esta tarea concreta. Es probable que mejores eligiendo la palabra etiquetada a partir de los ojos, pero la evidencia de que esto se transfiera a la habilidad social cotidiana o a la empat\xeda es d\xe9bil y discutida."],["\xbfPor qu\xe9 algunas respuestas son tan dif\xedciles aunque los ojos parezcan obvios?","A menudo el cuello de botella son las palabras, no el rostro. Las opciones incluyen t\xe9rminos sutiles y poco comunes, as\xed que si no conoces con precisi\xf3n una palabra como 'contemplativo' o 'aprensivo' puedes leer la emoci\xf3n correctamente y aun as\xed elegir mal."]],variants:"Hay una versi\xf3n infantil con un lenguaje m\xe1s sencillo, y ediciones traducidas a muchos idiomas con claves de respuesta validadas localmente. Ejercicios afines usan rostros completos en lugar de solo los ojos, videoclips din\xe1micos de expresiones, o se\xf1ales de voz y postura corporal, y algunas apps a\xf1aden un cron\xf3metro o retroalimentaci\xf3n tras cada \xedtem."},de:{about:"Dir wird ein Nahaufnahmen-Foto gezeigt, das nur auf die Augenpartie eines Gesichts zugeschnitten ist, mit vier W\xf6rtern f\xfcr Gef\xfchle oder mentale Zust\xe4nde ringsherum (zum Beispiel: eifers\xfcchtig, panisch, arrogant, hasserf\xfcllt). Deine Aufgabe ist es, das eine Wort zu w\xe4hlen, das am besten beschreibt, was die Person denkt oder f\xfchlt. Der Standardsatz umfasst 36 Fotos.",benefit:"Trainiert wird die soziale Kognition: subtile emotionale und mentale Zust\xe4nde allein aus den Augen abzulesen, dazu der Gef\xfchlswortschatz, den du brauchst, um diese Zust\xe4nde pr\xe4zise zu benennen. Praktisch gesprochen \xfcbst du die schnelle, feink\xf6rnige Deutung von Gesichtshinweisen.",history:"Es begann als psychologisches Forschungsinstrument, nicht als Spiel. Die Gruppe um Simon Baron-Cohen stellte den urspr\xfcnglichen \u201eEyes Test\u201c 1997 als fortgeschrittenes Ma\xdf der Theory of Mind f\xfcr Erwachsene vor und ver\xf6ffentlichte 2001 eine \xfcberarbeitete Version, nachdem die erste kritisiert worden war. Er verbreitete sich rasch, wurde in weit \xfcber 250 Studien eingesetzt und in viele Sprachen \xfcbersetzt, und das Augen-und-W\xf6rter-Format wurde sp\xe4ter zu beliebten Online-Quizzes und Gehirntrainings-\xdcbungen umgem\xfcnzt.",creator:"Simon Baron-Cohen und Kollegen an der University of Cambridge. Der urspr\xfcngliche Test stammt von 1997; die weit verbreitete \xfcberarbeitete Version (Baron-Cohen, Wheelwright, Hill, Raste und Plumb) wurde 2001 im Journal of Child Psychology and Psychiatry ver\xf6ffentlicht.",methods:"Schau zuerst auf die Augen und bilde dir einen Eindruck, bevor du die vier W\xf6rter liest, damit die Begriffe dich nicht beeinflussen. Achte auf konkrete Hinweise \u2013 die Offenheit der Lider, den Winkel der Brauen, die Blickrichtung \u2013 und schlie\xdfe die Optionen aus, die eindeutig nicht passen. Wenn du eine verfehlst, halt inne und lerne das Wort: Viele Fehler sind Wortschatzl\xfccken, keine Wahrnehmungsl\xfccken, sodass ein reicherer Gef\xfchlswortschatz dein Ergebnis direkt anhebt.",duration:"Kurze Sitzungen funktionieren am besten: Ein Durchgang von 36 Gesichtern dauert nur ein paar Minuten. Zwei oder drei fokussierte Sitzungen pro Woche reichen aus; die Eintr\xe4ge durchzugehen, die du falsch hattest, z\xe4hlt mehr als blo\xdfe Menge.",research:"Solide ist: Der Test trennt Gruppen im Mittel zuverl\xe4ssig, autistische Erwachsene schneiden tendenziell schlechter ab als nicht-autistische, und Meta-Analysen berichten einen kleinen Vorteil f\xfcr Frauen. Mit \xdcbung wirst du au\xdferdem besser in der Aufgabe selbst. Wackelig ist: Eine wachsende Zahl von Arbeiten stellt infrage, was er eigentlich misst, und argumentiert, er erfasse wom\xf6glich eher das Wissen um Gef\xfchlsw\xf6rter und deren Wiedererkennung als echtes \u201eGedankenlesen\u201c, und berichtet eine schwache interne Konsistenz und eine schlechte Faktorstruktur, wobei sich einige Eintr\xe4ge ung\xfcnstig verhalten. Zusammenh\xe4nge mit selbstberichteter Empathie sind uneinheitlich, und der bekannte Befund, dass Oxytocin die Eyes-Test-Werte steigert, lie\xdf sich kaum replizieren. Behandle Behauptungen, er trainiere breite soziale Kompetenz oder Empathie im echten Leben, als unbewiesen.",rec:"Behandle jeden Fehler als Vokabellektion, nicht blo\xdf als falsche Vermutung, und schlage das genaue Wort nach, bevor du weitergehst.",faq:[["Ist ein niedriger Wert ein Zeichen f\xfcr Autismus?","Nein. Er wurde als Forschungsma\xdf auf Gruppenebene gebaut, nicht als diagnostisches Werkzeug. Die Werte schwanken auch unter Menschen ohne Autismus stark, und f\xfcr sich allein sagt ein niedriger Wert sehr wenig \xfcber eine einzelne Person aus."],["Macht mich das \xdcben besser darin, Menschen im echten Leben zu lesen?","Vor allem macht es dich besser in dieser konkreten Aufgabe. Du wirst dich wahrscheinlich darin verbessern, aus den Augen das benannte Wort herauszupicken, aber die Belege, dass sich das auf allt\xe4gliche soziale Kompetenz oder Empathie \xfcbertr\xe4gt, sind schwach und umstritten."],["Warum sind manche Antworten so schwer, selbst wenn die Augen eindeutig wirken?","Oft ist der Engpass die W\xf6rter, nicht das Gesicht. Die Optionen enthalten subtile, seltene Begriffe \u2013 wenn du ein Wort wie \u201enachdenklich\u201c oder \u201ebesorgt\u201c nicht genau kennst, kannst du das Gef\xfchl richtig lesen und trotzdem falsch w\xe4hlen."]],variants:"Es gibt eine Kinderversion mit einfacherem Wortlaut und \xfcbersetzte Ausgaben in vielen Sprachen mit lokal validierten L\xf6sungsschl\xfcsseln. Verwandte \xdcbungen verwenden ganze Gesichter statt nur der Augen, dynamische Videoclips von Ausdr\xfccken oder Hinweise aus Stimme und K\xf6rperhaltung, und einige Apps erg\xe4nzen einen Timer oder eine R\xfcckmeldung nach jedem Eintrag."},pt:{about:"Mostra-se uma foto em close recortada apenas na regi\xe3o dos olhos de um rosto, com quatro palavras de emo\xe7\xe3o ou estado mental ao redor (por exemplo: com ci\xfame, em p\xe2nico, arrogante, cheio de \xf3dio). A sua tarefa \xe9 escolher a \xfanica palavra que melhor descreve o que a pessoa est\xe1 pensando ou sentindo. O conjunto padr\xe3o tem 36 fotos.",benefit:"Treina a cogni\xe7\xe3o social: ler estados emocionais e mentais subtis apenas a partir dos olhos, al\xe9m do vocabul\xe1rio de emo\xe7\xf5es de que voc\xea precisa para rotular esses estados com precis\xe3o. Na pr\xe1tica, voc\xea exercita a interpreta\xe7\xe3o r\xe1pida e detalhada de pistas faciais.",history:"Come\xe7ou como instrumento de investiga\xe7\xe3o em psicologia, n\xe3o como jogo. O grupo de Simon Baron-Cohen apresentou o 'Teste dos Olhos' original em 1997 como uma medida avan\xe7ada de teoria da mente para adultos e depois lan\xe7ou uma vers\xe3o revista em 2001, ap\xf3s o primeiro ter sido criticado. Espalhou-se depressa, foi usado em bem mais de 250 estudos e traduzido para muitas l\xednguas, e o formato de olhos e palavras foi mais tarde adaptado a populares question\xe1rios online e exerc\xedcios de treino cerebral.",creator:"Simon Baron-Cohen e colegas da Universidade de Cambridge. O teste original \xe9 de 1997; a vers\xe3o revista amplamente usada (Baron-Cohen, Wheelwright, Hill, Raste e Plumb) foi publicada em 2001 no Journal of Child Psychology and Psychiatry.",methods:"Olhe primeiro para os olhos e forme uma impress\xe3o antes de ler as quatro palavras, para que os r\xf3tulos n\xe3o enviesem voc\xea. Preste aten\xe7\xe3o a pistas concretas, \xe0 abertura das p\xe1lpebras, ao \xe2ngulo das sobrancelhas, \xe0 dire\xe7\xe3o do olhar, e elimine as op\xe7\xf5es que claramente n\xe3o encaixam. Quando errar uma, pare e aprenda a palavra: muitos erros s\xe3o lacunas de vocabul\xe1rio, n\xe3o de percep\xe7\xe3o, por isso construir um vocabul\xe1rio de sentimentos mais rico aumenta diretamente a sua pontua\xe7\xe3o.",duration:"As sess\xf5es curtas funcionam melhor: uma passagem pelas 36 fotos leva apenas alguns minutos. Duas ou tr\xeas sess\xf5es focadas por semana \xe9 o suficiente; rever os itens que voc\xea errou importa mais do que o volume bruto.",research:"O que \xe9 s\xf3lido: o teste separa de forma fi\xe1vel os grupos em m\xe9dia, adultos autistas tendem a pontuar mais baixo do que adultos n\xe3o autistas, e as meta-an\xe1lises relatam uma pequena vantagem feminina. Com a pr\xe1tica voc\xea tamb\xe9m melhora na pr\xf3pria tarefa. O que \xe9 fr\xe1gil: um conjunto crescente de trabalhos questiona o que ele de fato mede, argumentando que talvez recrute mais o conhecimento e o reconhecimento de palavras de emo\xe7\xe3o do que uma genu\xedna 'leitura da mente', e relata baixa consist\xeancia interna e uma estrutura fatorial pobre, com alguns itens a comportar-se mal. A liga\xe7\xe3o \xe0 empatia autorrelatada \xe9 inconsistente, e o conhecido achado de que a oxitocina eleva as pontua\xe7\xf5es no Teste dos Olhos tem tido dificuldade em replicar. Encare como n\xe3o comprovadas as alega\xe7\xf5es de que ele treina uma habilidade social ou uma empatia amplas no mundo real.",rec:"Trate cada erro como uma li\xe7\xe3o de vocabul\xe1rio, n\xe3o apenas como um palpite errado, e procure a palavra exata antes de seguir em frente.",faq:[["Uma pontua\xe7\xe3o baixa \xe9 sinal de autismo?","N\xe3o. Foi constru\xeddo como uma medida de investiga\xe7\xe3o ao n\xedvel do grupo, n\xe3o como ferramenta de diagn\xf3stico. As pontua\xe7\xf5es variam muito entre pessoas sem autismo e, por si s\xf3, uma pontua\xe7\xe3o baixa diz muito pouco sobre qualquer indiv\xedduo."],["Pratic\xe1-lo vai me deixar melhor a ler as pessoas na vida real?","Na maior parte, deixa voc\xea melhor nesta tarefa espec\xedfica. Voc\xea provavelmente vai melhorar a escolher a palavra rotulada a partir dos olhos, mas a evid\xeancia de que isso se transfere para a habilidade social ou a empatia do dia a dia \xe9 fraca e contestada."],["Por que algumas respostas s\xe3o t\xe3o dif\xedceis mesmo quando os olhos parecem \xf3bvios?","Muitas vezes o gargalo s\xe3o as palavras, n\xe3o o rosto. As op\xe7\xf5es incluem termos subtis e pouco comuns, ent\xe3o, se voc\xea n\xe3o conhece com precis\xe3o uma palavra como 'contemplativo' ou 'apreensivo', pode ler a emo\xe7\xe3o corretamente e ainda assim escolher errado."]],variants:"Existe uma vers\xe3o infantil com palavras mais simples e edi\xe7\xf5es traduzidas em muitas l\xednguas, com gabaritos validados localmente. Exerc\xedcios relacionados usam rostos inteiros em vez de apenas os olhos, videoclipes din\xe2micos de express\xf5es ou pistas de voz e de postura corporal, e alguns aplicativos acrescentam um cron\xf3metro ou feedback ap\xf3s cada item."},hi:{about:"\u0906\u092a\u0915\u094b \u0915\u093f\u0938\u0940 \u091a\u0947\u0939\u0930\u0947 \u0915\u0940 \u0938\u093f\u0930\u094d\u092b\u093c \u0906\u0901\u0916\u094b\u0902 \u0935\u093e\u0932\u0947 \u0939\u093f\u0938\u094d\u0938\u0947 \u0924\u0915 \u0915\u093e\u091f\u0940 \u0917\u0908 \u090f\u0915 \u0928\u091c\u093c\u0926\u0940\u0915\u0940 \u0924\u0938\u094d\u0935\u0940\u0930 \u0926\u093f\u0916\u093e\u0908 \u091c\u093e\u0924\u0940 \u0939\u0948, \u091c\u093f\u0938\u0915\u0947 \u091a\u093e\u0930\u094b\u0902 \u0913\u0930 \u092d\u093e\u0935\u0928\u093e \u092f\u093e \u092e\u093e\u0928\u0938\u093f\u0915-\u0938\u094d\u0925\u093f\u0924\u093f \u0915\u0947 \u091a\u093e\u0930 \u0936\u092c\u094d\u0926 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902 (\u092e\u0938\u0932\u0928: \u0908\u0930\u094d\u0937\u094d\u092f\u093e\u0932\u0941, \u0918\u092c\u0930\u093e\u092f\u093e \u0939\u0941\u0906, \u0918\u092e\u0902\u0921\u0940, \u0928\u092b\u093c\u0930\u0924-\u092d\u0930\u093e)\u0964 \u0906\u092a\u0915\u093e \u0915\u093e\u092e \u0939\u0948 \u0935\u0939 \u0905\u0915\u0947\u0932\u093e \u0936\u092c\u094d\u0926 \u091a\u0941\u0928\u0928\u093e \u091c\u094b \u0938\u092c\u0938\u0947 \u0905\u091a\u094d\u091b\u0940 \u0924\u0930\u0939 \u092c\u0924\u093e\u090f \u0915\u093f \u0935\u0939 \u0935\u094d\u092f\u0915\u094d\u0924\u093f \u0915\u094d\u092f\u093e \u0938\u094b\u091a \u092f\u093e \u092e\u0939\u0938\u0942\u0938 \u0915\u0930 \u0930\u0939\u093e \u0939\u0948\u0964 \u092e\u093e\u0928\u0915 \u0938\u0947\u091f \u092e\u0947\u0902 36 \u0924\u0938\u094d\u0935\u0940\u0930\u0947\u0902 \u0939\u094b\u0924\u0940 \u0939\u0948\u0902\u0964",benefit:"\u092f\u0939 \u0938\u093e\u092e\u093e\u091c\u093f\u0915 \u0938\u0902\u091c\u094d\u091e\u093e\u0928 \u0915\u094b \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u093f\u0924 \u0915\u0930\u0924\u093e \u0939\u0948: \u0938\u093f\u0930\u094d\u092b\u093c \u0906\u0901\u0916\u094b\u0902 \u0938\u0947 \u0938\u0942\u0915\u094d\u0937\u094d\u092e \u092d\u093e\u0935\u0928\u093e\u0924\u094d\u092e\u0915 \u0914\u0930 \u092e\u093e\u0928\u0938\u093f\u0915 \u0938\u094d\u0925\u093f\u0924\u093f\u092f\u093e\u0901 \u092a\u0922\u093c\u0928\u093e, \u0938\u093e\u0925 \u0939\u0940 \u0909\u0928 \u0938\u094d\u0925\u093f\u0924\u093f\u092f\u094b\u0902 \u0915\u094b \u0938\u091f\u0940\u0915 \u0928\u093e\u092e \u0926\u0947\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u091c\u093c\u0930\u0942\u0930\u0940 \u092d\u093e\u0935\u0928\u093e-\u0936\u092c\u094d\u0926\u093e\u0935\u0932\u0940\u0964 \u0935\u094d\u092f\u093e\u0935\u0939\u093e\u0930\u093f\u0915 \u0930\u0942\u092a \u092e\u0947\u0902 \u0906\u092a \u091a\u0947\u0939\u0930\u0947 \u0915\u0947 \u0938\u0942\u0915\u094d\u0937\u094d\u092e \u0938\u0902\u0915\u0947\u0924\u094b\u0902 \u0915\u0940 \u0924\u094d\u0935\u0930\u093f\u0924, \u092c\u093e\u0930\u0940\u0915 \u0935\u094d\u092f\u093e\u0916\u094d\u092f\u093e \u0915\u0940 \u0915\u0938\u0930\u0924 \u0915\u0930 \u0930\u0939\u0947 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902\u0964",history:"\u0907\u0938\u0915\u0940 \u0936\u0941\u0930\u0941\u0906\u0924 \u090f\u0915 \u0916\u0947\u0932 \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u0928\u0939\u0940\u0902, \u092c\u0932\u094d\u0915\u093f \u090f\u0915 \u092e\u0928\u094b\u0935\u093f\u091c\u094d\u091e\u093e\u0928 \u0936\u094b\u0927-\u0909\u092a\u0915\u0930\u0923 \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u0939\u0941\u0908\u0964 Simon Baron-Cohen \u0915\u0947 \u0938\u092e\u0942\u0939 \u0928\u0947 \u092e\u0942\u0932 'Eyes Test' \u0915\u094b 1997 \u092e\u0947\u0902 \u0935\u092f\u0938\u094d\u0915\u094b\u0902 \u0915\u0947 \u0932\u093f\u090f \u090f\u0915 \u0909\u0928\u094d\u0928\u0924 theory-of-mind \u092e\u093e\u092a \u0915\u0947 \u0924\u094c\u0930 \u092a\u0930 \u092a\u0947\u0936 \u0915\u093f\u092f\u093e, \u092b\u093f\u0930 \u092a\u0939\u0932\u0947 \u0935\u093e\u0932\u0947 \u0915\u0940 \u0906\u0932\u094b\u091a\u0928\u093e \u0939\u094b\u0928\u0947 \u0915\u0947 \u092c\u093e\u0926 2001 \u092e\u0947\u0902 \u090f\u0915 \u0938\u0902\u0936\u094b\u0927\u093f\u0924 \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u091c\u093e\u0930\u0940 \u0915\u093f\u092f\u093e\u0964 \u092f\u0939 \u0924\u0947\u091c\u093c\u0940 \u0938\u0947 \u092b\u0948\u0932\u093e, 250 \u0938\u0947 \u0915\u0939\u0940\u0902 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0905\u0927\u094d\u092f\u092f\u0928\u094b\u0902 \u092e\u0947\u0902 \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0939\u0941\u0906 \u0914\u0930 \u0915\u0908 \u092d\u093e\u0937\u093e\u0913\u0902 \u092e\u0947\u0902 \u0905\u0928\u0942\u0926\u093f\u0924 \u0939\u0941\u0906, \u0914\u0930 \u0906\u0901\u0916\u0947\u0902-\u0914\u0930-\u0936\u092c\u094d\u0926 \u0935\u093e\u0932\u093e \u092f\u0939 \u092a\u094d\u0930\u093e\u0930\u0942\u092a \u092c\u093e\u0926 \u092e\u0947\u0902 \u0932\u094b\u0915\u092a\u094d\u0930\u093f\u092f \u0911\u0928\u0932\u093e\u0907\u0928 \u0915\u094d\u0935\u093f\u091c\u093c \u0914\u0930 \u092c\u094d\u0930\u0947\u0928-\u091f\u094d\u0930\u0947\u0928\u093f\u0902\u0917 \u0905\u092d\u094d\u092f\u093e\u0938\u094b\u0902 \u092e\u0947\u0902 \u0922\u093e\u0932 \u0932\u093f\u092f\u093e \u0917\u092f\u093e\u0964",creator:"University of Cambridge \u092e\u0947\u0902 Simon Baron-Cohen \u0914\u0930 \u0938\u093e\u0925\u0940\u0964 \u092e\u0942\u0932 \u092a\u0930\u0940\u0915\u094d\u0937\u0923 1997 \u0915\u093e \u0939\u0948; \u0935\u094d\u092f\u093e\u092a\u0915 \u0930\u0942\u092a \u0938\u0947 \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0939\u094b\u0928\u0947 \u0935\u093e\u0932\u093e \u0938\u0902\u0936\u094b\u0927\u093f\u0924 \u0938\u0902\u0938\u094d\u0915\u0930\u0923 (Baron-Cohen, Wheelwright, Hill, Raste \u0914\u0930 Plumb) 2001 \u092e\u0947\u0902 Journal of Child Psychology and Psychiatry \u092e\u0947\u0902 \u092a\u094d\u0930\u0915\u093e\u0936\u093f\u0924 \u0939\u0941\u0906\u0964",methods:"\u092a\u0939\u0932\u0947 \u0906\u0901\u0916\u094b\u0902 \u0915\u094b \u0926\u0947\u0916\u0947\u0902 \u0914\u0930 \u091a\u093e\u0930 \u0936\u092c\u094d\u0926 \u092a\u0922\u093c\u0928\u0947 \u0938\u0947 \u092a\u0939\u0932\u0947 \u0939\u0940 \u090f\u0915 \u0927\u093e\u0930\u0923\u093e \u092c\u0928\u093e \u0932\u0947\u0902, \u0924\u093e\u0915\u093f \u0932\u0947\u092c\u0932 \u0906\u092a \u092a\u0930 \u0905\u0938\u0930 \u0928 \u0921\u093e\u0932\u0947\u0902\u0964 \u0920\u094b\u0938 \u0938\u0902\u0915\u0947\u0924\u094b\u0902 \u092a\u0930 \u0927\u094d\u092f\u093e\u0928 \u0926\u0947\u0902 \u2014 \u092a\u0932\u0915\u094b\u0902 \u0915\u093e \u0916\u0941\u0932\u093e\u092a\u0928, \u092d\u094c\u0902\u0939\u094b\u0902 \u0915\u093e \u0915\u094b\u0923, \u0928\u093f\u0917\u093e\u0939 \u0915\u0940 \u0926\u093f\u0936\u093e \u2014 \u0914\u0930 \u091c\u094b \u0935\u093f\u0915\u0932\u094d\u092a \u0938\u093e\u092b\u093c \u0924\u094c\u0930 \u092a\u0930 \u092b\u093c\u093f\u091f \u0928\u0939\u0940\u0902 \u092c\u0948\u0920\u0924\u0947 \u0909\u0928\u094d\u0939\u0947\u0902 \u091b\u093e\u0901\u091f \u0926\u0947\u0902\u0964 \u091c\u092c \u0915\u094b\u0908 \u091b\u0942\u091f \u091c\u093e\u090f, \u0924\u094b \u0930\u0941\u0915\u0915\u0930 \u0935\u0939 \u0936\u092c\u094d\u0926 \u0938\u0940\u0916\u0947\u0902: \u092c\u0939\u0941\u0924-\u0938\u0940 \u0917\u0932\u0924\u093f\u092f\u093e\u0901 \u0936\u092c\u094d\u0926\u093e\u0935\u0932\u0940 \u0915\u0940 \u0915\u092e\u0940 \u0939\u094b\u0924\u0940 \u0939\u0948\u0902, \u0927\u093e\u0930\u0923\u093e \u0915\u0940 \u0928\u0939\u0940\u0902, \u0907\u0938\u0932\u093f\u090f \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0938\u092e\u0943\u0926\u094d\u0927 \u092d\u093e\u0935\u0928\u093e-\u0936\u092c\u094d\u0926\u093e\u0935\u0932\u0940 \u092c\u0928\u093e\u0928\u093e \u0938\u0940\u0927\u0947 \u0906\u092a\u0915\u093e \u0938\u094d\u0915\u094b\u0930 \u092c\u0922\u093c\u093e\u0924\u093e \u0939\u0948\u0964",duration:"\u091b\u094b\u091f\u0947 \u0938\u0924\u094d\u0930 \u0938\u092c\u0938\u0947 \u0905\u091a\u094d\u091b\u0947 \u0930\u0939\u0924\u0947 \u0939\u0948\u0902: 36 \u091a\u0947\u0939\u0930\u094b\u0902 \u0915\u093e \u090f\u0915 \u0926\u094c\u0930 \u092c\u0938 \u0915\u0941\u091b \u0939\u0940 \u092e\u093f\u0928\u091f \u0932\u0947\u0924\u093e \u0939\u0948\u0964 \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u0926\u094b-\u0924\u0940\u0928 \u0915\u0947\u0902\u0926\u094d\u0930\u093f\u0924 \u0938\u0924\u094d\u0930 \u0915\u093e\u092b\u093c\u0940 \u0939\u0948\u0902; \u091c\u094b \u0906\u0907\u091f\u092e \u0906\u092a\u0928\u0947 \u0917\u0932\u0924 \u0915\u093f\u090f \u0909\u0928\u0915\u0940 \u0938\u092e\u0940\u0915\u094d\u0937\u093e \u0915\u0930\u0928\u093e \u092d\u093e\u0930\u0940 \u092e\u093e\u0924\u094d\u0930\u093e \u0938\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u092e\u093e\u092f\u0928\u0947 \u0930\u0916\u0924\u093e \u0939\u0948\u0964",research:"\u091c\u094b \u092a\u0941\u0916\u093c\u094d\u0924\u093e \u0939\u0948: \u092f\u0939 \u092a\u0930\u0940\u0915\u094d\u0937\u0923 \u0914\u0938\u0924\u0928 \u0938\u092e\u0942\u0939\u094b\u0902 \u0915\u094b \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0922\u0902\u0917 \u0938\u0947 \u0905\u0932\u0917 \u0915\u0930\u0924\u093e \u0939\u0948, \u0911\u091f\u093f\u0938\u094d\u091f\u093f\u0915 \u0935\u092f\u0938\u094d\u0915 \u0917\u093c\u0948\u0930-\u0911\u091f\u093f\u0938\u094d\u091f\u093f\u0915 \u0935\u092f\u0938\u094d\u0915\u094b\u0902 \u0915\u0940 \u0924\u0941\u0932\u0928\u093e \u092e\u0947\u0902 \u0928\u0940\u091a\u0947 \u0938\u094d\u0915\u094b\u0930 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u092e\u0947\u091f\u093e-\u0935\u093f\u0936\u094d\u0932\u0947\u0937\u0923 \u090f\u0915 \u091b\u094b\u091f\u0940-\u0938\u0940 \u092e\u0939\u093f\u0932\u093e \u092c\u0922\u093c\u0924 \u092c\u0924\u093e\u0924\u0947 \u0939\u0948\u0902\u0964 \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0947 \u0938\u093e\u0925 \u0906\u092a \u0916\u0941\u0926 \u0907\u0938 \u0915\u093e\u0930\u094d\u092f \u092e\u0947\u0902 \u092d\u0940 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902\u0964 \u091c\u094b \u0921\u0917\u092e\u0917 \u0939\u0948: \u092c\u0922\u093c\u0924\u093e \u0939\u0941\u0906 \u0915\u093e\u092e \u0907\u0938 \u092a\u0930 \u0938\u0935\u093e\u0932 \u0909\u0920\u093e\u0924\u093e \u0939\u0948 \u0915\u093f \u092f\u0939 \u0905\u0938\u0932 \u092e\u0947\u0902 \u0915\u094d\u092f\u093e \u0928\u093e\u092a\u0924\u093e \u0939\u0948 \u2014 \u092f\u0939 \u0924\u0930\u094d\u0915 \u0926\u0947\u0924\u0947 \u0939\u0941\u090f \u0915\u093f \u092f\u0939 \u0938\u091a\u094d\u091a\u0940 '\u092e\u0928-\u092a\u0922\u093c\u093e\u0908' \u0938\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u092d\u093e\u0935\u0928\u093e-\u0936\u092c\u094d\u0926\u094b\u0902 \u0915\u0947 \u091c\u094d\u091e\u093e\u0928 \u0914\u0930 \u092a\u0939\u091a\u093e\u0928 \u0915\u094b \u091f\u091f\u094b\u0932 \u0938\u0915\u0924\u093e \u0939\u0948 \u2014 \u0914\u0930 \u0915\u092e\u091c\u093c\u094b\u0930 \u0906\u0902\u0924\u0930\u093f\u0915 \u0938\u0902\u0917\u0924\u093f \u0924\u0925\u093e \u0916\u093c\u0930\u093e\u092c \u092b\u093c\u0948\u0915\u094d\u091f\u0930-\u0938\u0902\u0930\u091a\u0928\u093e \u0915\u0940 \u0930\u093f\u092a\u094b\u0930\u094d\u091f \u0915\u0930\u0924\u093e \u0939\u0948, \u091c\u093f\u0938\u092e\u0947\u0902 \u0915\u0941\u091b \u0906\u0907\u091f\u092e \u0920\u0940\u0915 \u0938\u0947 \u092c\u0930\u094d\u0924\u093e\u0935 \u0928\u0939\u0940\u0902 \u0915\u0930\u0924\u0947\u0964 \u0938\u094d\u0935-\u092c\u0924\u093e\u0908 \u0938\u0939\u093e\u0928\u0941\u092d\u0942\u0924\u093f \u0938\u0947 \u0907\u0938\u0915\u0947 \u091c\u0941\u0921\u093c\u093e\u0935 \u0905\u0938\u0902\u0917\u0924 \u0939\u0948\u0902, \u0914\u0930 \u092f\u0939 \u092e\u0936\u0939\u0942\u0930 \u0928\u0924\u0940\u091c\u093e \u0915\u093f \u0911\u0915\u094d\u0938\u0940\u091f\u094b\u0938\u093f\u0928 Eyes-Test \u0938\u094d\u0915\u094b\u0930 \u092c\u0922\u093c\u093e\u0924\u093e \u0939\u0948, \u0926\u094b\u092c\u093e\u0930\u093e \u0938\u093e\u092c\u093f\u0924 \u0939\u094b\u0928\u0947 \u092e\u0947\u0902 \u091c\u0942\u091d\u0924\u093e \u0930\u0939\u093e \u0939\u0948\u0964 \u0907\u0928 \u0926\u093e\u0935\u094b\u0902 \u0915\u094b \u0905\u092a\u094d\u0930\u092e\u093e\u0923\u093f\u0924 \u092e\u093e\u0928\u0947\u0902 \u0915\u093f \u092f\u0939 \u0935\u093e\u0938\u094d\u0924\u0935\u093f\u0915 \u0926\u0941\u0928\u093f\u092f\u093e \u0915\u0947 \u0935\u094d\u092f\u093e\u092a\u0915 \u0938\u093e\u092e\u093e\u091c\u093f\u0915 \u0915\u094c\u0936\u0932 \u092f\u093e \u0938\u0939\u093e\u0928\u0941\u092d\u0942\u0924\u093f \u0915\u094b \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u093f\u0924 \u0915\u0930\u0924\u093e \u0939\u0948\u0964",rec:"\u0939\u0930 \u091a\u0942\u0915 \u0915\u094b \u0938\u093f\u0930\u094d\u092b\u093c \u090f\u0915 \u0917\u0932\u0924 \u0905\u0902\u0926\u093e\u091c\u093c\u093e \u0928\u0939\u0940\u0902, \u092c\u0932\u094d\u0915\u093f \u090f\u0915 \u0936\u092c\u094d\u0926\u093e\u0935\u0932\u0940-\u092a\u093e\u0920 \u092e\u093e\u0928\u0947\u0902, \u0914\u0930 \u0906\u0917\u0947 \u092c\u0922\u093c\u0928\u0947 \u0938\u0947 \u092a\u0939\u0932\u0947 \u0909\u0938 \u0938\u091f\u0940\u0915 \u0936\u092c\u094d\u0926 \u0915\u094b \u0922\u0942\u0901\u0922\u0915\u0930 \u0926\u0947\u0916 \u0932\u0947\u0902\u0964",faq:[["\u0915\u094d\u092f\u093e \u0915\u092e \u0938\u094d\u0915\u094b\u0930 \u0911\u091f\u093f\u091c\u093c\u094d\u092e \u0915\u093e \u0938\u0902\u0915\u0947\u0924 \u0939\u0948?","\u0928\u0939\u0940\u0902\u0964 \u0907\u0938\u0947 \u0938\u092e\u0942\u0939-\u0938\u094d\u0924\u0930 \u0915\u0947 \u0936\u094b\u0927-\u092e\u093e\u092a \u0915\u0947 \u0924\u094c\u0930 \u092a\u0930 \u092c\u0928\u093e\u092f\u093e \u0917\u092f\u093e \u0925\u093e, \u0915\u093f\u0938\u0940 \u0928\u0948\u0926\u093e\u0928\u093f\u0915 \u0914\u091c\u093c\u093e\u0930 \u0915\u0947 \u0924\u094c\u0930 \u092a\u0930 \u0928\u0939\u0940\u0902\u0964 \u0911\u091f\u093f\u091c\u093c\u094d\u092e \u0930\u0939\u093f\u0924 \u0932\u094b\u0917\u094b\u0902 \u092e\u0947\u0902 \u092d\u0940 \u0938\u094d\u0915\u094b\u0930 \u092c\u0939\u0941\u0924 \u0905\u0932\u0917-\u0905\u0932\u0917 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u0905\u0915\u0947\u0932\u0947 \u090f\u0915 \u0915\u092e \u0938\u094d\u0915\u094b\u0930 \u0915\u093f\u0938\u0940 \u0935\u094d\u092f\u0915\u094d\u0924\u093f \u0915\u0947 \u092c\u093e\u0930\u0947 \u092e\u0947\u0902 \u092c\u0939\u0941\u0924 \u0915\u092e \u092c\u0924\u093e\u0924\u093e \u0939\u0948\u0964"],["\u0915\u094d\u092f\u093e \u0907\u0938\u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u092e\u0941\u091d\u0947 \u0905\u0938\u0932 \u091c\u093c\u093f\u0902\u0926\u0917\u0940 \u092e\u0947\u0902 \u0932\u094b\u0917\u094b\u0902 \u0915\u094b \u092a\u0922\u093c\u0928\u0947 \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u092c\u0928\u093e \u0926\u0947\u0917\u093e?","\u091c\u093c\u094d\u092f\u093e\u0926\u093e\u0924\u0930 \u092f\u0939 \u0906\u092a\u0915\u094b \u0907\u0938\u0940 \u0916\u093e\u0938 \u0915\u093e\u0930\u094d\u092f \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u092c\u0928\u093e\u0924\u093e \u0939\u0948\u0964 \u0906\u092a \u0936\u093e\u092f\u0926 \u0906\u0901\u0916\u094b\u0902 \u0938\u0947 \u0932\u0947\u092c\u0932 \u0935\u093e\u0932\u093e \u0936\u092c\u094d\u0926 \u091a\u0941\u0928\u0928\u0947 \u092e\u0947\u0902 \u0938\u0941\u0927\u0930\u0947\u0902\u0917\u0947, \u092a\u0930 \u0907\u0938 \u092c\u093e\u0924 \u0915\u0947 \u0938\u092c\u0942\u0924 \u0915\u092e\u091c\u093c\u094b\u0930 \u0914\u0930 \u0935\u093f\u0935\u093e\u0926\u093f\u0924 \u0939\u0948\u0902 \u0915\u093f \u092f\u0939 \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0947 \u0938\u093e\u092e\u093e\u091c\u093f\u0915 \u0915\u094c\u0936\u0932 \u092f\u093e \u0938\u0939\u093e\u0928\u0941\u092d\u0942\u0924\u093f \u0924\u0915 \u0938\u094d\u0925\u093e\u0928\u093e\u0902\u0924\u0930\u093f\u0924 \u0939\u094b\u0924\u093e \u0939\u0948\u0964"],["\u0915\u0941\u091b \u091c\u0935\u093e\u092c \u0907\u0924\u0928\u0947 \u0915\u0920\u093f\u0928 \u0915\u094d\u092f\u094b\u0902 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902, \u091c\u092c\u0915\u093f \u0906\u0901\u0916\u0947\u0902 \u0938\u093e\u092b\u093c \u0926\u093f\u0916\u0924\u0940 \u0939\u0948\u0902?","\u0905\u0915\u0938\u0930 \u0905\u0921\u093c\u091a\u0928 \u0936\u092c\u094d\u0926 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902, \u091a\u0947\u0939\u0930\u093e \u0928\u0939\u0940\u0902\u0964 \u0935\u093f\u0915\u0932\u094d\u092a\u094b\u0902 \u092e\u0947\u0902 \u0938\u0942\u0915\u094d\u0937\u094d\u092e, \u0915\u092e \u091a\u0932\u0928\u0947 \u0935\u093e\u0932\u0947 \u0936\u092c\u094d\u0926 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902, \u0907\u0938\u0932\u093f\u090f \u0905\u0917\u0930 \u0906\u092a 'contemplative' \u092f\u093e 'apprehensive' \u091c\u0948\u0938\u0947 \u0915\u093f\u0938\u0940 \u0936\u092c\u094d\u0926 \u0915\u094b \u0920\u0940\u0915-\u0920\u0940\u0915 \u0928\u0939\u0940\u0902 \u091c\u093e\u0928\u0924\u0947, \u0924\u094b \u0906\u092a \u092d\u093e\u0935\u0928\u093e \u0938\u0939\u0940 \u092a\u0922\u093c\u0915\u0930 \u092d\u0940 \u0917\u0932\u0924 \u0935\u093f\u0915\u0932\u094d\u092a \u091a\u0941\u0928 \u0938\u0915\u0924\u0947 \u0939\u0948\u0902\u0964"]],variants:"\u090f\u0915 \u092c\u091a\u094d\u091a\u094b\u0902 \u0935\u093e\u0932\u093e \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0939\u0948 \u091c\u093f\u0938\u092e\u0947\u0902 \u0936\u092c\u094d\u0926 \u0906\u0938\u093e\u0928 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u0915\u0908 \u092d\u093e\u0937\u093e\u0913\u0902 \u092e\u0947\u0902 \u0905\u0928\u0942\u0926\u093f\u0924 \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0939\u0948\u0902 \u091c\u093f\u0928\u0915\u0940 \u0909\u0924\u094d\u0924\u0930-\u0915\u0941\u0902\u091c\u093f\u092f\u093e\u0901 \u0938\u094d\u0925\u093e\u0928\u0940\u092f \u0930\u0942\u092a \u0938\u0947 \u092e\u093e\u0928\u094d\u092f \u0915\u0940 \u0917\u0908 \u0939\u0948\u0902\u0964 \u092e\u093f\u0932\u0924\u0947-\u091c\u0941\u0932\u0924\u0947 \u0905\u092d\u094d\u092f\u093e\u0938 \u0938\u093f\u0930\u094d\u092b\u093c \u0906\u0901\u0916\u094b\u0902 \u0915\u0947 \u092c\u091c\u093e\u092f \u092a\u0942\u0930\u0947 \u091a\u0947\u0939\u0930\u0947, \u092d\u093e\u0935\u094b\u0902 \u0915\u0947 \u0917\u0924\u093f\u0936\u0940\u0932 \u0935\u0940\u0921\u093f\u092f\u094b \u0915\u094d\u0932\u093f\u092a, \u092f\u093e \u0906\u0935\u093e\u091c\u093c \u0914\u0930 \u0936\u0930\u0940\u0930-\u092e\u0941\u0926\u094d\u0930\u093e \u0915\u0947 \u0938\u0902\u0915\u0947\u0924 \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u0915\u0941\u091b \u0910\u092a\u094d\u0938 \u0939\u0930 \u0906\u0907\u091f\u092e \u0915\u0947 \u092c\u093e\u0926 \u090f\u0915 \u091f\u093e\u0907\u092e\u0930 \u092f\u093e \u092b\u093c\u0940\u0921\u092c\u0948\u0915 \u091c\u094b\u0921\u093c \u0926\u0947\u0924\u0947 \u0939\u0948\u0902\u0964"},zh:{about:"\u4f60\u4f1a\u770b\u5230\u4e00\u5f20\u7279\u5199\u7167\u7247\uff0c\u53ea\u88c1\u51fa\u4e00\u5f20\u8138\u7684\u773c\u775b\u90e8\u4f4d\uff0c\u5468\u56f4\u6709\u56db\u4e2a\u63cf\u8ff0\u60c5\u7eea\u6216\u5fc3\u7406\u72b6\u6001\u7684\u8bcd\uff08\u4f8b\u5982\uff1a\u5ac9\u5992\u3001\u60ca\u614c\u3001\u50b2\u6162\u3001\u618e\u6068\uff09\u3002\u4f60\u7684\u4efb\u52a1\u662f\u6311\u51fa\u6700\u80fd\u63cf\u8ff0\u8fd9\u4e2a\u4eba\u6b63\u5728\u60f3\u4ec0\u4e48\u6216\u611f\u53d7\u4ec0\u4e48\u7684\u90a3\u4e00\u4e2a\u8bcd\u3002\u6807\u51c6\u9898\u7ec4\u5171 36 \u5f20\u7167\u7247\u3002",benefit:"\u5b83\u8bad\u7ec3\u793e\u4f1a\u8ba4\u77e5\uff1a\u4ec5\u51ed\u773c\u775b\u8bfb\u51fa\u5fae\u5999\u7684\u60c5\u7eea\u548c\u5fc3\u7406\u72b6\u6001\uff0c\u5916\u52a0\u4f60\u9700\u8981\u7528\u6765\u7cbe\u786e\u6807\u6ce8\u8fd9\u4e9b\u72b6\u6001\u7684\u60c5\u7eea\u8bcd\u6c47\u3002\u5177\u4f53\u6765\u8bf4\uff0c\u4f60\u5728\u953b\u70bc\u7684\u662f\u5bf9\u9762\u90e8\u7ebf\u7d22\u5feb\u901f\u800c\u7cbe\u7ec6\u7684\u89e3\u8bfb\u3002",history:"\u5b83\u8d77\u521d\u662f\u4e00\u4ef6\u5fc3\u7406\u5b66\u7814\u7a76\u5de5\u5177\uff0c\u800c\u975e\u6e38\u620f\u3002Simon Baron-Cohen \u7684\u56e2\u961f\u4e8e 1997 \u5e74\u63a8\u51fa\u4e86\u6700\u521d\u7684\u300c\u773c\u795e\u6d4b\u9a8c\u300d\uff0c\u4f5c\u4e3a\u9762\u5411\u6210\u4eba\u7684\u9ad8\u7ea7\u5fc3\u7406\u7406\u8bba\u6d4b\u91cf\uff1b\u5728\u6700\u521d\u7248\u672c\u53d7\u5230\u6279\u8bc4\u540e\uff0c\u4ed6\u4eec\u4e8e 2001 \u5e74\u53d1\u5e03\u4e86\u4fee\u8ba2\u7248\u3002\u5b83\u4f20\u64ad\u5f88\u5feb\uff0c\u5df2\u88ab\u7528\u4e8e\u8fdc\u8d85 250 \u9879\u7814\u7a76\u5e76\u8bd1\u6210\u591a\u79cd\u8bed\u8a00\uff0c\u800c\u300c\u773c\u775b\u914d\u8bcd\u8bed\u300d\u7684\u5f62\u5f0f\u540e\u6765\u8fd8\u88ab\u6539\u7f16\u6210\u6d41\u884c\u7684\u5728\u7ebf\u6d4b\u9a8c\u548c\u5927\u8111\u8bad\u7ec3\u7ec3\u4e60\u3002",creator:"\u5251\u6865\u5927\u5b66\u7684 Simon Baron-Cohen \u53ca\u5176\u540c\u4e8b\u3002\u6700\u521d\u7684\u6d4b\u9a8c\u51fa\u81ea 1997 \u5e74\uff1b\u5e7f\u6cdb\u4f7f\u7528\u7684\u4fee\u8ba2\u7248\uff08Baron-Cohen\u3001Wheelwright\u3001Hill\u3001Raste \u548c Plumb\uff09\u4e8e 2001 \u5e74\u53d1\u8868\u5728\u300aJournal of Child Psychology and Psychiatry\u300b\u4e0a\u3002",methods:"\u5148\u770b\u773c\u775b\uff0c\u5728\u8bfb\u90a3\u56db\u4e2a\u8bcd\u4e4b\u524d\u5148\u5f62\u6210\u4e00\u4e2a\u5370\u8c61\uff0c\u8fd9\u6837\u6807\u7b7e\u5c31\u4e0d\u4f1a\u5e26\u504f\u4f60\u7684\u5224\u65ad\u3002\u7559\u610f\u5177\u4f53\u7ebf\u7d22\uff1a\u773c\u7751\u5f20\u5f00\u7684\u7a0b\u5ea6\u3001\u7709\u6bdb\u7684\u89d2\u5ea6\u3001\u89c6\u7ebf\u7684\u65b9\u5411\uff0c\u5e76\u6392\u9664\u90a3\u4e9b\u660e\u663e\u4e0d\u5408\u7684\u9009\u9879\u3002\u5f53\u4f60\u7b54\u9519\u65f6\uff0c\u505c\u4e0b\u6765\u628a\u90a3\u4e2a\u8bcd\u5b66\u4f1a\uff1a\u5f88\u591a\u9519\u8bef\u662f\u8bcd\u6c47\u7a7a\u7f3a\uff0c\u800c\u975e\u77e5\u89c9\u7a7a\u7f3a\uff0c\u6240\u4ee5\u5efa\u7acb\u66f4\u4e30\u5bcc\u7684\u60c5\u7eea\u8bcd\u6c47\u4f1a\u76f4\u63a5\u62c9\u9ad8\u4f60\u7684\u5206\u6570\u3002",duration:"\u77ed\u65f6\u6bb5\u7ec3\u4e60\u6548\u679c\u6700\u597d\uff1a\u628a 36 \u5f20\u8138\u8fc7\u4e00\u904d\u53ea\u9700\u51e0\u5206\u949f\u3002\u6bcf\u5468\u4e24\u5230\u4e09\u6b21\u4e13\u6ce8\u7684\u7ec3\u4e60\u5c31\u8db3\u591f\u4e86\uff1b\u590d\u4e60\u7b54\u9519\u7684\u9898\u76ee\u6bd4\u5355\u7eaf\u5806\u91cf\u66f4\u91cd\u8981\u3002",research:"\u624e\u5b9e\u7684\u90e8\u5206\uff1a\u8be5\u6d4b\u9a8c\u80fd\u53ef\u9760\u5730\u5728\u5e73\u5747\u6c34\u5e73\u4e0a\u533a\u5206\u7fa4\u4f53\uff0c\u81ea\u95ed\u75c7\u6210\u4eba\u7684\u5f97\u5206\u5f80\u5f80\u4f4e\u4e8e\u975e\u81ea\u95ed\u75c7\u6210\u4eba\uff0c\u5143\u5206\u6790\u4e5f\u62a5\u544a\u4e86\u5973\u6027\u6709\u5fae\u5c0f\u7684\u4f18\u52bf\u3002\u968f\u7740\u7ec3\u4e60\uff0c\u4f60\u4e5f\u4f1a\u5728\u4efb\u52a1\u672c\u8eab\u4e0a\u53d8\u597d\u3002\u4e0d\u7262\u9760\u7684\u90e8\u5206\uff1a\u8d8a\u6765\u8d8a\u591a\u7684\u7814\u7a76\u8d28\u7591\u5b83\u5230\u5e95\u6d4b\u7684\u662f\u4ec0\u4e48\uff0c\u8ba4\u4e3a\u5b83\u53ef\u80fd\u66f4\u591a\u89e6\u53ca\u7684\u662f\u60c5\u7eea\u8bcd\u77e5\u8bc6\u548c\u518d\u8ba4\uff0c\u800c\u975e\u771f\u6b63\u7684\u300c\u8bfb\u5fc3\u300d\uff0c\u5e76\u62a5\u544a\u5176\u5185\u90e8\u4e00\u81f4\u6027\u5f31\u3001\u56e0\u7d20\u7ed3\u6784\u5dee\uff0c\u4e00\u4e9b\u9898\u76ee\u8868\u73b0\u4e0d\u4f73\u3002\u5b83\u4e0e\u81ea\u8bc4\u5171\u60c5\u7684\u5173\u8054\u5e76\u4e0d\u4e00\u81f4\uff0c\u800c\u300c\u50ac\u4ea7\u7d20\u80fd\u63d0\u5347\u773c\u795e\u6d4b\u9a8c\u5206\u6570\u300d\u8fd9\u4e00\u8457\u540d\u53d1\u73b0\u4e5f\u96be\u4ee5\u590d\u73b0\u3002\u628a\u300c\u5b83\u80fd\u8bad\u7ec3\u5e7f\u6cdb\u7684\u73b0\u5b9e\u793e\u4ea4\u80fd\u529b\u6216\u5171\u60c5\u300d\u4e4b\u7c7b\u7684\u8bf4\u6cd5\u5f53\u4f5c\u672a\u7ecf\u8bc1\u5b9e\u3002",rec:"\u628a\u6bcf\u4e00\u6b21\u7b54\u9519\u90fd\u5f53\u6210\u4e00\u5802\u8bcd\u6c47\u8bfe\uff0c\u800c\u4e0d\u4ec5\u4ec5\u662f\u4e00\u6b21\u731c\u9519\uff0c\u5e76\u5728\u5f80\u4e0b\u8d70\u4e4b\u524d\u67e5\u6e05\u90a3\u4e2a\u786e\u5207\u7684\u8bcd\u3002",faq:[["\u5206\u6570\u4f4e\u662f\u81ea\u95ed\u75c7\u7684\u4fe1\u53f7\u5417\uff1f","\u4e0d\u662f\u3002\u5b83\u662f\u4f5c\u4e3a\u7fa4\u4f53\u5c42\u9762\u7684\u7814\u7a76\u6d4b\u91cf\u9020\u51fa\u6765\u7684\uff0c\u800c\u975e\u8bca\u65ad\u5de5\u5177\u3002\u6ca1\u6709\u81ea\u95ed\u75c7\u7684\u4eba\u4e4b\u95f4\u5206\u6570\u5dee\u5f02\u4e5f\u5f88\u5927\uff0c\u5355\u51ed\u4e00\u4e2a\u4f4e\u5206\uff0c\u5173\u4e8e\u4efb\u4f55\u4e2a\u4f53\u5b83\u90fd\u51e0\u4e4e\u8bf4\u660e\u4e0d\u4e86\u4ec0\u4e48\u3002"],["\u7ec3\u5b83\u4f1a\u8ba9\u6211\u5728\u73b0\u5b9e\u4e2d\u66f4\u4f1a\u8bfb\u4eba\u5417\uff1f","\u5b83\u4e3b\u8981\u662f\u8ba9\u4f60\u66f4\u64c5\u957f\u8fd9\u9879\u5177\u4f53\u4efb\u52a1\u3002\u4f60\u5f88\u53ef\u80fd\u4f1a\u66f4\u64c5\u957f\u4ece\u773c\u775b\u91cc\u6311\u51fa\u90a3\u4e2a\u88ab\u6807\u6ce8\u7684\u8bcd\uff0c\u4f46\u80fd\u5426\u8fc1\u79fb\u5230\u65e5\u5e38\u793e\u4ea4\u80fd\u529b\u6216\u5171\u60c5\uff0c\u8bc1\u636e\u5f88\u5f31\u3001\u6709\u4e89\u8bae\u3002"],["\u4e3a\u4ec0\u4e48\u6709\u4e9b\u7b54\u6848\u660e\u660e\u773c\u775b\u770b\u7740\u5f88\u660e\u663e\u5374\u90a3\u4e48\u96be\uff1f","\u74f6\u9888\u5f80\u5f80\u5728\u8bcd\uff0c\u800c\u4e0d\u5728\u8138\u3002\u9009\u9879\u91cc\u5305\u542b\u5fae\u5999\u3001\u4e0d\u5e38\u89c1\u7684\u8bcd\uff0c\u6240\u4ee5\u5982\u679c\u4f60\u4e0d\u7cbe\u786e\u77e5\u9053\u50cf\u300c\u6c89\u601d\u7684\u300d\u6216\u300c\u5fe7\u60e7\u7684\u300d\u8fd9\u6837\u7684\u8bcd\uff0c\u4f60\u53ef\u80fd\u6b63\u786e\u8bfb\u51fa\u4e86\u60c5\u7eea\uff0c\u5374\u4ecd\u7136\u9009\u9519\u3002"]],variants:"\u6709\u7528\u8bcd\u66f4\u7b80\u5355\u7684\u513f\u7ae5\u7248\uff0c\u4e5f\u6709\u591a\u79cd\u8bed\u8a00\u3001\u914d\u6709\u672c\u5730\u9a8c\u8bc1\u7b54\u6848\u952e\u7684\u8bd1\u672c\u3002\u76f8\u5173\u7684\u7ec3\u4e60\u6539\u7528\u6574\u5f20\u8138\u800c\u975e\u53ea\u770b\u773c\u775b\uff0c\u6216\u4f7f\u7528\u8868\u60c5\u7684\u52a8\u6001\u89c6\u9891\u7247\u6bb5\uff0c\u6216\u4f7f\u7528\u55d3\u97f3\u548c\u8eab\u4f53\u59ff\u6001\u7ebf\u7d22\uff0c\u8fd8\u6709\u4e00\u4e9b\u5e94\u7528\u4f1a\u52a0\u4e0a\u8ba1\u65f6\u5668\u6216\u5728\u6bcf\u9898\u540e\u7ed9\u51fa\u53cd\u9988\u3002"}},schulte:{ru:{about:"\u0422\u0430\u0431\u043b\u0438\u0446\u0430 \u0428\u0443\u043b\u044c\u0442\u0435 \u2014 \u0441\u0435\u0442\u043a\u0430 \u0441\u043e \u0441\u043b\u0443\u0447\u0430\u0439\u043d\u043e \u0440\u0430\u0441\u0441\u0442\u0430\u0432\u043b\u0435\u043d\u043d\u044b\u043c\u0438 \u0447\u0438\u0441\u043b\u0430\u043c\u0438 (\u043e\u0431\u044b\u0447\u043d\u043e 5\xd75). \u0417\u0430\u0434\u0430\u0447\u0430 \u2014 \u043d\u0430\u0445\u043e\u0434\u0438\u0442\u044c \u0438 \u043d\u0430\u0436\u0438\u043c\u0430\u0442\u044c \u0438\u0445 \u043f\u043e \u043f\u043e\u0440\u044f\u0434\u043a\u0443, \u043e\u0442 1 \u0434\u043e N, \u043a\u0430\u043a \u043c\u043e\u0436\u043d\u043e \u0431\u044b\u0441\u0442\u0440\u0435\u0435, \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u044f \u0432\u0437\u0433\u043b\u044f\u0434 \u0443 \u0446\u0435\u043d\u0442\u0440\u0430.",benefit:"\u0421\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u0433\u043e \u043f\u043e\u0438\u0441\u043a\u0430, \u0448\u0438\u0440\u0438\u043d\u0443 \u043f\u0435\u0440\u0438\u0444\u0435\u0440\u0438\u0447\u0435\u0441\u043a\u043e\u0433\u043e \u0437\u0440\u0435\u043d\u0438\u044f, \u0443\u0441\u0442\u043e\u0439\u0447\u0438\u0432\u043e\u0441\u0442\u044c \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f \u0438 \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044c \u0444\u0438\u043a\u0441\u0430\u0446\u0438\u0438 \u0432\u0437\u0433\u043b\u044f\u0434\u0430 \u2014 \u043e\u0441\u043d\u043e\u0432\u0443 \u0431\u044b\u0441\u0442\u0440\u043e\u0433\u043e \u0447\u0442\u0435\u043d\u0438\u044f.",history:"\u0412 1950-\u0435 \u0441\u043e\u0437\u0434\u0430\u0432\u0430\u043b\u0430\u0441\u044c \u043a\u0430\u043a \u043a\u043b\u0438\u043d\u0438\u0447\u0435\u0441\u043a\u0438\u0439 \u0438\u043d\u0441\u0442\u0440\u0443\u043c\u0435\u043d\u0442 \u0434\u043b\u044f \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u044f \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f, \u043f\u043e\u0437\u0436\u0435 \u0432\u043e\u0448\u043b\u0430 \u0432 \u043e\u0431\u0440\u0430\u0437\u043e\u0432\u0430\u043d\u0438\u0435 \u0438 \u043a\u0443\u0440\u0441\u044b \u0441\u043a\u043e\u0440\u043e\u0447\u0442\u0435\u043d\u0438\u044f. \u041d\u0430 \u043f\u043e\u0441\u0442\u0441\u043e\u0432\u0435\u0442\u0441\u043a\u043e\u043c \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435 \u2014 \u043e\u0434\u043d\u043e \u0438\u0437 \u0441\u0430\u043c\u044b\u0445 \u0438\u0437\u0432\u0435\u0441\u0442\u043d\u044b\u0445 \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u0439 \u043d\u0430 \u043a\u043e\u043d\u0446\u0435\u043d\u0442\u0440\u0430\u0446\u0438\u044e.",creator:"\u041d\u0435\u043c\u0435\u0446\u043a\u0438\u0439 \u043f\u0441\u0438\u0445\u0438\u0430\u0442\u0440 \u0412\u0430\u043b\u044c\u0442\u0435\u0440 \u0428\u0443\u043b\u044c\u0442\u0435 \u2014 \u043e\u043d \u043f\u0440\u0438\u0434\u0443\u043c\u0430\u043b \u0442\u0430\u0431\u043b\u0438\u0446\u0443 \u0432 1950-\u0435 \u043a\u0430\u043a \u043f\u0441\u0438\u0445\u043e\u0434\u0438\u0430\u0433\u043d\u043e\u0441\u0442\u0438\u0447\u0435\u0441\u043a\u0438\u0439 \u0442\u0435\u0441\u0442 \u0434\u043b\u044f \u043e\u0446\u0435\u043d\u043a\u0438 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f \u0438 \u0440\u0430\u0431\u043e\u0442\u043e\u0441\u043f\u043e\u0441\u043e\u0431\u043d\u043e\u0441\u0442\u0438.",methods:"\u0414\u0435\u0440\u0436\u0438 \u0432\u0437\u0433\u043b\u044f\u0434 \u0432 \u0446\u0435\u043d\u0442\u0440\u0430\u043b\u044c\u043d\u043e\u0439 \u043a\u043b\u0435\u0442\u043a\u0435 \u0438 \u0438\u0449\u0438 \u0441\u043b\u0435\u0434\u0443\u044e\u0449\u0435\u0435 \u0447\u0438\u0441\u043b\u043e \u043f\u0435\u0440\u0438\u0444\u0435\u0440\u0438\u0447\u0435\u0441\u043a\u0438\u043c \u0437\u0440\u0435\u043d\u0438\u0435\u043c, \u0430 \u043d\u0435 \u0431\u0435\u0433\u0430\u0439 \u0433\u043b\u0430\u0437\u0430\u043c\u0438. \u041d\u0430\u0447\u0438\u043d\u0430\u0439 \u0441 5\xd75; \u043d\u0430 7\xd77 \u043f\u0435\u0440\u0435\u0445\u043e\u0434\u0438, \u043a\u043e\u0433\u0434\u0430 \u043e\u0434\u043d\u0430 \u0442\u0430\u0431\u043b\u0438\u0446\u0430 \u0437\u0430\u043d\u0438\u043c\u0430\u0435\u0442 \u043c\u0435\u043d\u044c\u0448\u0435 ~40 \u0441\u0435\u043a\u0443\u043d\u0434.",duration:"\u0420\u0430\u0431\u043e\u0442\u0430\u0435\u0442 \u043a\u043e\u0440\u043e\u0442\u043a\u043e\u0435 \u0438 \u0440\u0435\u0433\u0443\u043b\u044f\u0440\u043d\u043e\u0435: 5\u201310 \u043c\u0438\u043d\u0443\u0442, 1\u20132 \u0442\u0430\u0431\u043b\u0438\u0446\u044b \u0432 \u0434\u0435\u043d\u044c. \u041e\u0431\u044b\u0447\u043d\u043e \u0432\u0440\u0435\u043c\u044f \u043d\u0430 \u0442\u0430\u0431\u043b\u0438\u0446\u0443 \u043f\u0430\u0434\u0430\u0435\u0442 \u0437\u0430 \u043f\u0435\u0440\u0432\u044b\u0435 2\u20133 \u043d\u0435\u0434\u0435\u043b\u0438, \u043f\u043e\u0442\u043e\u043c \u0432\u044b\u0445\u043e\u0434\u0438\u0442 \u043d\u0430 \u043f\u043b\u0430\u0442\u043e.",research:"\u0421\u0438\u043b\u044c\u043d\u0435\u0435 \u0432\u0441\u0435\u0433\u043e \u0434\u043e\u043a\u0430\u0437\u0430\u043d\u043e \u043e\u0436\u0438\u0434\u0430\u0435\u043c\u043e\u0435 \u2014 \u0440\u0430\u0441\u0442\u0451\u0442 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u0433\u043e \u043f\u043e\u0438\u0441\u043a\u0430 \u0438 \u0440\u0430\u0441\u0448\u0438\u0440\u044f\u0435\u0442\u0441\u044f \u043f\u043e\u043b\u0435 \u0437\u0440\u0435\u043d\u0438\u044f. \u0423\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043d\u0438\u044f \u043f\u0440\u043e \u0440\u043e\u0441\u0442 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u0438 \u0447\u0442\u0435\u043d\u0438\u044f \u0438\u043b\u0438 \xab\u043e\u0431\u0449\u0435\u0433\u043e \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442\u0430\xbb \u0441\u043b\u0430\u0431\u0435\u0435 \u0438 \u0441\u0438\u043b\u044c\u043d\u043e \u0437\u0430\u0432\u0438\u0441\u044f\u0442 \u043e\u0442 \u043c\u0435\u0442\u043e\u0434\u0438\u043a\u0438; \u043a \u0433\u0440\u043e\u043c\u043a\u0438\u043c \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f\u043c \u043e\u0442\u043d\u043e\u0441\u0438\u0441\u044c \u043e\u0441\u0442\u043e\u0440\u043e\u0436\u043d\u043e.",rec:"\u0418\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0439 \u043a\u0430\u043a 5-\u043c\u0438\u043d\u0443\u0442\u043d\u0443\u044e \u0440\u0430\u0437\u043c\u0438\u043d\u043a\u0443 \u043f\u0435\u0440\u0435\u0434 \u0440\u0430\u0431\u043e\u0442\u043e\u0439, \u0442\u0440\u0435\u0431\u0443\u044e\u0449\u0435\u0439 \u043a\u043e\u043d\u0446\u0435\u043d\u0442\u0440\u0430\u0446\u0438\u0438. \u0413\u043e\u043d\u0438\u0441\u044c \u0437\u0430 \u0441\u0432\u043e\u0438\u043c \u043b\u0443\u0447\u0448\u0438\u043c \u0432\u0440\u0435\u043c\u0435\u043d\u0435\u043c, \u0430 \u043d\u0435 \u0447\u0443\u0436\u0438\u043c, \u0438 \u0437\u0430\u043a\u0430\u043d\u0447\u0438\u0432\u0430\u0439, \u043f\u043e\u043a\u0430 \u0434\u0435\u0440\u0436\u0438\u0448\u044c \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u044c.",faq:[["\u0420\u0435\u0430\u043b\u044c\u043d\u043e \u0443\u0441\u043a\u043e\u0440\u044f\u0435\u0442 \u0447\u0442\u0435\u043d\u0438\u0435?","\u0422\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u0444\u0438\u043a\u0441\u0430\u0446\u0438\u044e \u0438 \u043f\u0435\u0440\u0438\u0444\u0435\u0440\u0438\u044e, \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u0447\u0442\u0435\u043d\u0438\u0435 \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0435\u0442, \u043d\u043e \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u0447\u0442\u0435\u043d\u0438\u044f \u0437\u0430\u0432\u0438\u0441\u0438\u0442 \u0435\u0449\u0451 \u043e\u0442 \u0441\u043b\u043e\u0432\u0430\u0440\u044f \u0438 \u043f\u043e\u043d\u0438\u043c\u0430\u043d\u0438\u044f \u2014 \u0442\u0430\u0431\u043b\u0438\u0446\u0430 \u044d\u0442\u043e \u043e\u0434\u0438\u043d \u044d\u043b\u0435\u043c\u0435\u043d\u0442, \u043d\u0435 \u0432\u043e\u043b\u0448\u0435\u0431\u043d\u044b\u0439 \u0442\u0443\u043c\u0431\u043b\u0435\u0440."],["\u0421 \u043a\u0430\u043a\u043e\u0433\u043e \u0440\u0430\u0437\u043c\u0435\u0440\u0430 \u043d\u0430\u0447\u0430\u0442\u044c?","5\xd75. \u041d\u0430 6\xd76 \u0438\u043b\u0438 7\xd77 \u043f\u0435\u0440\u0435\u0445\u043e\u0434\u0438, \u043a\u043e\u0433\u0434\u0430 \u0442\u0430\u0431\u043b\u0438\u0446\u0430 \u0441\u0442\u0430\u0431\u0438\u043b\u044c\u043d\u043e \u0437\u0430\u043d\u0438\u043c\u0430\u0435\u0442 \u043c\u0435\u043d\u044c\u0448\u0435 ~40 \u0441\u0435\u043a\u0443\u043d\u0434."],["\u041a\u0430\u043a \u0447\u0430\u0441\u0442\u043e \u0437\u0430\u043d\u0438\u043c\u0430\u0442\u044c\u0441\u044f?","\u0415\u0436\u0435\u0434\u043d\u0435\u0432\u043d\u043e, \u043f\u043e \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u043c\u0438\u043d\u0443\u0442. \u0427\u0430\u0441\u0442\u043e\u0442\u0430 \u0432\u0430\u0436\u043d\u0435\u0435 \u0434\u043b\u0438\u043d\u043d\u044b\u0445 \u0441\u0435\u0441\u0441\u0438\u0439."]],variants:"\u0411\u043e\u0301\u043b\u044c\u0448\u0438\u0435 \u0441\u0435\u0442\u043a\u0438 (6\xd76, 7\xd77); \u0446\u0432\u0435\u0442\u043d\u044b\u0435 \u0442\u0430\u0431\u043b\u0438\u0446\u044b \u0413\u043e\u0440\u0431\u043e\u0432\u0430\u2013\u0428\u0443\u043b\u044c\u0442\u0435 \u0441 \u0447\u0435\u0440\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u0435\u043c \u0434\u0432\u0443\u0445 \u043f\u043e\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u0435\u0439; \u0432\u0435\u0440\u0441\u0438\u0438 \u0441 \u0431\u0443\u043a\u0432\u0430\u043c\u0438 \u0438\u043b\u0438 \u0441\u0438\u043c\u0432\u043e\u043b\u0430\u043c\u0438."},en:{about:"A Schulte table is a grid of randomly arranged numbers (usually 5\xd75). Your job is to find and tap them in order, 1 to N, as fast as possible while keeping your gaze fixed near the centre.",benefit:"Speed of visual search, the breadth of your peripheral vision, sustained attention, and the gaze-fixation control that underlies fast reading.",history:"Built in the 1950s as a clinical instrument for examining attention, it later spread into education and speed-reading courses. Across Russian-speaking countries it is one of the best-known focus exercises.",creator:"German psychiatrist Walter Schulte, who designed the grid in the 1950s as a psychodiagnostic test for attention and work-capacity disorders.",methods:"Keep your eyes on the centre cell and locate the next number with peripheral vision instead of darting around. Start at 5\xd75; only drop to easier grids if accuracy slips, and scale up to 7\xd77 once a board takes under ~40 seconds.",duration:"Short and regular wins: 5\u201310 minutes, one or two boards a day. Most people watch their per-board time fall over the first 2\u20133 weeks, then plateau.",research:"Evidence is strongest for exactly what you would expect \u2014 you get faster at visual search and your useful field of view widens. Claims that it boosts reading speed or general intelligence are weaker and depend heavily on how you practise, so treat the grand promises with caution.",rec:"Use it as a 5-minute warm-up before focused work. Chase your own best time, not someone else's, and end the session while you are still accurate.",faq:[["Does it really speed up reading?","It trains the fixation and peripheral skills reading uses, but faster reading also needs vocabulary and comprehension work \u2014 the table is one piece, not a magic switch."],["What grid size should I start with?","5\xd75. Move to 6\xd76 or 7\xd77 only when a board reliably takes under ~40 seconds."],["How often should I practise?","Daily, a few minutes. Frequency matters more than long sessions."]],variants:"Larger grids (6\xd76, 7\xd77); colour-and-number Gorbov\u2013Schulte tables where you alternate two sequences; and letter or symbol versions."},es:{about:"Una tabla de Schulte es una cuadr\xedcula con n\xfameros colocados al azar (normalmente de 5\xd75). Tu tarea es encontrarlos y tocarlos en orden, del 1 al N, lo m\xe1s r\xe1pido posible mientras mantienes la mirada fija cerca del centro.",benefit:"La velocidad de b\xfasqueda visual, la amplitud de tu visi\xf3n perif\xe9rica, la atenci\xf3n sostenida y el control de fijaci\xf3n de la mirada en el que se apoya la lectura r\xe1pida.",history:"Creada en los a\xf1os cincuenta como instrumento cl\xednico para examinar la atenci\xf3n, m\xe1s tarde se extendi\xf3 a la educaci\xf3n y a los cursos de lectura r\xe1pida. En los pa\xedses de habla rusa es uno de los ejercicios de concentraci\xf3n m\xe1s conocidos.",creator:"El psiquiatra alem\xe1n Walter Schulte, que dise\xf1\xf3 la cuadr\xedcula en los a\xf1os cincuenta como prueba psicodiagn\xf3stica para los trastornos de la atenci\xf3n y de la capacidad de trabajo.",methods:"Mant\xe9n la vista en la casilla central y localiza el siguiente n\xfamero con la visi\xf3n perif\xe9rica, en lugar de saltar de un lado a otro. Empieza con 5\xd75; baja a cuadr\xedculas m\xe1s f\xe1ciles solo si la precisi\xf3n decae, y sube a 7\xd77 cuando un tablero te lleve menos de unos 40 segundos.",duration:"Lo que funciona es poco y a menudo: de 5 a 10 minutos, uno o dos tableros al d\xeda. La mayor\xeda ve c\xf3mo su tiempo por tablero baja durante las primeras 2 o 3 semanas y luego se estanca.",research:"La evidencia es m\xe1s s\xf3lida justo en lo que cabr\xeda esperar: te vuelves m\xe1s r\xe1pido en la b\xfasqueda visual y tu campo de visi\xf3n \xfatil se ensancha. Las afirmaciones de que mejora la velocidad de lectura o la inteligencia general son m\xe1s d\xe9biles y dependen mucho de c\xf3mo practiques, as\xed que toma con cautela las grandes promesas.",rec:"\xdasala como calentamiento de 5 minutos antes del trabajo que exige concentraci\xf3n. Persigue tu propio mejor tiempo, no el de los dem\xe1s, y termina la sesi\xf3n mientras sigas siendo preciso.",faq:[["\xbfDe verdad acelera la lectura?","Entrena la fijaci\xf3n y las destrezas perif\xe9ricas que la lectura usa, pero leer m\xe1s r\xe1pido tambi\xe9n requiere trabajar el vocabulario y la comprensi\xf3n: la tabla es una pieza m\xe1s, no un interruptor m\xe1gico."],["\xbfCon qu\xe9 tama\xf1o de cuadr\xedcula deber\xeda empezar?","Con 5\xd75. Pasa a 6\xd76 o 7\xd77 solo cuando un tablero te lleve de forma constante menos de unos 40 segundos."],["\xbfCon qu\xe9 frecuencia deber\xeda practicar?","A diario, unos pocos minutos. La frecuencia importa m\xe1s que las sesiones largas."]],variants:"Cuadr\xedculas m\xe1s grandes (6\xd76, 7\xd77); tablas de Gorbov-Schulte con color y n\xfamero en las que alternas dos secuencias; y versiones con letras o s\xedmbolos."},de:{about:"Eine Schulte-Tabelle ist ein Raster aus zuf\xe4llig angeordneten Zahlen (meist 5\xd75). Deine Aufgabe ist es, sie der Reihe nach von 1 bis N zu finden und anzutippen \u2013 so schnell wie m\xf6glich, w\xe4hrend dein Blick nahe der Mitte fixiert bleibt.",benefit:"Geschwindigkeit der visuellen Suche, die Weite deines peripheren Sehens, anhaltende Aufmerksamkeit und die Blickfixierung, auf der schnelles Lesen beruht.",history:"In den 1950er-Jahren als klinisches Instrument zur Untersuchung der Aufmerksamkeit entwickelt, fand die Tabelle sp\xe4ter Eingang in Bildung und Schnelllesekurse. Im russischsprachigen Raum ist sie eine der bekanntesten Konzentrations\xfcbungen \xfcberhaupt.",creator:"Der deutsche Psychiater Walter Schulte, der das Raster in den 1950er-Jahren als psychodiagnostischen Test f\xfcr St\xf6rungen der Aufmerksamkeit und Leistungsf\xe4higkeit entwarf.",methods:"Halte den Blick auf der mittleren Zelle und finde die n\xe4chste Zahl mit dem peripheren Sehen, statt mit den Augen umherzuspringen. Beginne mit 5\xd75; wechsle nur dann zu leichteren Rastern, wenn die Treffsicherheit nachl\xe4sst, und steigere dich auf 7\xd77, sobald eine Tafel weniger als rund 40 Sekunden braucht.",duration:"Kurz und regelm\xe4\xdfig gewinnt: 5\u201310 Minuten, ein oder zwei Tafeln am Tag. Bei den meisten sinkt die Zeit pro Tafel in den ersten 2\u20133 Wochen sp\xfcrbar und erreicht dann ein Plateau.",research:"Am besten belegt ist genau das, was man erwarten w\xfcrde: Du wirst schneller in der visuellen Suche, und dein nutzbares Sichtfeld weitet sich. Behauptungen, dass die \xdcbung das Lesetempo oder die allgemeine Intelligenz steigert, sind deutlich schw\xe4cher und h\xe4ngen stark davon ab, wie du \xfcbst \u2013 gro\xdfe Versprechen also mit Vorsicht genie\xdfen.",rec:"Nutze sie als 5-min\xfctiges Aufw\xe4rmen vor konzentrierter Arbeit. Jage deine eigene Bestzeit, nicht die anderer, und beende die Sitzung, solange du noch treffsicher bist.",faq:[["Beschleunigt sie wirklich das Lesen?","Sie trainiert die Fixierung und das periphere Sehen, die das Lesen nutzt \u2013 aber schnelleres Lesen braucht auch Wortschatz und Textverst\xe4ndnis. Die Tabelle ist ein Baustein, kein Zauberschalter."],["Mit welcher Rastergr\xf6\xdfe sollte ich anfangen?","Mit 5\xd75. Wechsle erst zu 6\xd76 oder 7\xd77, wenn eine Tafel zuverl\xe4ssig unter rund 40 Sekunden bleibt."],["Wie oft sollte ich \xfcben?","T\xe4glich, ein paar Minuten. Die H\xe4ufigkeit z\xe4hlt mehr als lange Sitzungen."]],variants:"Gr\xf6\xdfere Raster (6\xd76, 7\xd77); Farb-Zahl-Tabellen nach Gorbow-Schulte, bei denen du zwischen zwei Reihenfolgen wechselst; sowie Varianten mit Buchstaben oder Symbolen."},pt:{about:"A tabela de Schulte \xe9 uma grade de n\xfameros dispostos aleatoriamente (normalmente 5\xd75). Sua tarefa \xe9 encontr\xe1-los e toc\xe1-los em ordem, de 1 at\xe9 N, o mais r\xe1pido poss\xedvel, mantendo o olhar fixo perto do centro.",benefit:"Velocidade de busca visual, amplitude da vis\xe3o perif\xe9rica, aten\xe7\xe3o sustentada e o controle de fixa\xe7\xe3o do olhar que est\xe1 por tr\xe1s da leitura r\xe1pida.",history:"Criada nos anos 1950 como instrumento cl\xednico para avaliar a aten\xe7\xe3o, mais tarde se espalhou pela educa\xe7\xe3o e pelos cursos de leitura din\xe2mica. Nos pa\xedses de l\xedngua russa, \xe9 um dos exerc\xedcios de concentra\xe7\xe3o mais conhecidos.",creator:"O psiquiatra alem\xe3o Walter Schulte, que concebeu a grade nos anos 1950 como teste psicodiagn\xf3stico para transtornos de aten\xe7\xe3o e de capacidade de trabalho.",methods:"Mantenha os olhos na c\xe9lula central e localize o pr\xf3ximo n\xfamero com a vis\xe3o perif\xe9rica, em vez de ficar saltando de um lado para o outro. Comece com a 5\xd75; s\xf3 passe para grades mais f\xe1ceis se a precis\xe3o cair, e suba para a 7\xd77 assim que conseguir resolver um quadro em menos de uns 40 segundos.",duration:"Curto e regular \xe9 o que funciona: 5 a 10 minutos, um ou dois quadros por dia. A maioria das pessoas v\xea o tempo por quadro cair nas primeiras 2 a 3 semanas e depois estabilizar.",research:"A evid\xeancia \xe9 mais forte exatamente para o que se esperaria: voc\xea fica mais r\xe1pido na busca visual e seu campo visual \xfatil se amplia. As alega\xe7\xf5es de que a tabela aumenta a velocidade de leitura ou a intelig\xeancia geral s\xe3o mais fracas e dependem muito de como voc\xea treina, ent\xe3o encare as grandes promessas com cautela.",rec:"Use-a como um aquecimento de 5 minutos antes de um trabalho que exija concentra\xe7\xe3o. Persiga o seu pr\xf3prio melhor tempo, n\xe3o o dos outros, e encerre a sess\xe3o enquanto ainda estiver preciso.",faq:[["Ela realmente acelera a leitura?","Ela treina as habilidades de fixa\xe7\xe3o e de vis\xe3o perif\xe9rica que a leitura usa, mas ler mais r\xe1pido tamb\xe9m exige trabalhar vocabul\xe1rio e compreens\xe3o \u2014 a tabela \xe9 uma pe\xe7a, n\xe3o um bot\xe3o m\xe1gico."],["Com que tamanho de grade devo come\xe7ar?","5\xd75. Passe para a 6\xd76 ou a 7\xd77 s\xf3 quando um quadro levar, de forma consistente, menos de uns 40 segundos."],["Com que frequ\xeancia devo treinar?","Diariamente, alguns minutos. A frequ\xeancia importa mais do que sess\xf5es longas."]],variants:"Grades maiores (6\xd76, 7\xd77); as tabelas Gorbov\u2013Schulte coloridas com n\xfameros, em que voc\xea alterna duas sequ\xeancias; e vers\xf5es com letras ou s\xedmbolos."},hi:{about:"\u0936\u0941\u0932\u094d\u0924\u0947 \u091f\u0947\u092c\u0932 \u092f\u093e\u0926\u0943\u091a\u094d\u091b\u093f\u0915 \u0915\u094d\u0930\u092e \u092e\u0947\u0902 \u0932\u0917\u0940 \u0938\u0902\u0916\u094d\u092f\u093e\u0913\u0902 \u0915\u0940 \u090f\u0915 \u0917\u094d\u0930\u093f\u0921 \u0939\u094b\u0924\u0940 \u0939\u0948 (\u0906\u092e\u0924\u094c\u0930 \u092a\u0930 5\xd75)\u0964 \u0906\u092a\u0915\u093e \u0915\u093e\u092e \u0939\u0948 \u0907\u0928\u094d\u0939\u0947\u0902 1 \u0938\u0947 N \u0924\u0915 \u0915\u094d\u0930\u092e \u0938\u0947 \u0922\u0942\u0901\u0922\u0915\u0930 \u091c\u093f\u0924\u0928\u0940 \u0924\u0947\u091c\u093c\u0940 \u0938\u0947 \u0939\u094b \u0938\u0915\u0947 \u091b\u0942\u0928\u093e, \u0914\u0930 \u0938\u093e\u0925 \u0939\u0940 \u0905\u092a\u0928\u0940 \u0928\u091c\u093c\u0930 \u0915\u094b \u0917\u094d\u0930\u093f\u0921 \u0915\u0947 \u092c\u0940\u091a\u094b\u092c\u0940\u091a \u091f\u093f\u0915\u093e\u090f \u0930\u0916\u0928\u093e\u0964",benefit:"\u0926\u0943\u0936\u094d\u092f \u0916\u094b\u091c \u0915\u0940 \u0917\u0924\u093f, \u092a\u0930\u093f\u0927\u0940\u092f \u0926\u0943\u0937\u094d\u091f\u093f \u0915\u093e \u0926\u093e\u092f\u0930\u093e, \u0932\u0917\u093e\u0924\u093e\u0930 \u092c\u0928\u0940 \u0930\u0939\u0928\u0947 \u0935\u093e\u0932\u0940 \u090f\u0915\u093e\u0917\u094d\u0930\u0924\u093e, \u0914\u0930 \u0928\u091c\u093c\u0930 \u0915\u094b \u090f\u0915 \u091c\u0917\u0939 \u091f\u093f\u0915\u093e\u090f \u0930\u0916\u0928\u0947 \u0915\u093e \u0935\u0939\u0940 \u0928\u093f\u092f\u0902\u0924\u094d\u0930\u0923 \u091c\u094b \u0924\u0947\u091c\u093c \u092a\u0922\u093c\u0928\u0947 \u0915\u0940 \u0928\u0940\u0902\u0935 \u0939\u0948\u0964",history:"\u0907\u0938\u0947 1950 \u0915\u0947 \u0926\u0936\u0915 \u092e\u0947\u0902 \u0927\u094d\u092f\u093e\u0928 \u0915\u0940 \u091c\u093e\u0901\u091a \u0915\u0947 \u090f\u0915 \u0928\u0948\u0926\u093e\u0928\u093f\u0915 \u0909\u092a\u0915\u0930\u0923 \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u092c\u0928\u093e\u092f\u093e \u0917\u092f\u093e, \u0914\u0930 \u092c\u093e\u0926 \u092e\u0947\u0902 \u092f\u0939 \u0936\u093f\u0915\u094d\u0937\u093e \u0924\u0925\u093e \u0924\u0947\u091c\u093c-\u092a\u0920\u0928 \u0915\u0947 \u092a\u093e\u0920\u094d\u092f\u0915\u094d\u0930\u092e\u094b\u0902 \u092e\u0947\u0902 \u092b\u0948\u0932 \u0917\u092f\u093e\u0964 \u0930\u0942\u0938\u0940-\u092d\u093e\u0937\u0940 \u0926\u0947\u0936\u094b\u0902 \u092e\u0947\u0902 \u092f\u0939 \u090f\u0915\u093e\u0917\u094d\u0930\u0924\u093e \u0915\u0947 \u0938\u092c\u0938\u0947 \u091c\u093e\u0928\u0947-\u092e\u093e\u0928\u0947 \u0905\u092d\u094d\u092f\u093e\u0938\u094b\u0902 \u092e\u0947\u0902 \u0938\u0947 \u090f\u0915 \u0939\u0948\u0964",creator:"\u091c\u0930\u094d\u092e\u0928 \u092e\u0928\u094b\u091a\u093f\u0915\u093f\u0924\u094d\u0938\u0915 \u0935\u093e\u0932\u094d\u091f\u0930 \u0936\u0941\u0932\u094d\u0924\u0947, \u091c\u093f\u0928\u094d\u0939\u094b\u0902\u0928\u0947 1950 \u0915\u0947 \u0926\u0936\u0915 \u092e\u0947\u0902 \u0907\u0938 \u0917\u094d\u0930\u093f\u0921 \u0915\u094b \u0927\u094d\u092f\u093e\u0928 \u0914\u0930 \u0915\u093e\u0930\u094d\u092f-\u0915\u094d\u0937\u092e\u0924\u093e \u0938\u0902\u092c\u0902\u0927\u0940 \u0935\u093f\u0915\u093e\u0930\u094b\u0902 \u0915\u0940 \u091c\u093e\u0901\u091a \u0915\u0947 \u0932\u093f\u090f \u090f\u0915 \u092e\u0928\u094b\u0928\u093f\u0926\u093e\u0928 \u092a\u0930\u0940\u0915\u094d\u0937\u0923 \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u0924\u0948\u092f\u093e\u0930 \u0915\u093f\u092f\u093e\u0964",methods:"\u0905\u092a\u0928\u0940 \u0928\u091c\u093c\u0930 \u092c\u0940\u091a \u0915\u0940 \u0915\u094b\u0936\u093f\u0915\u093e \u092a\u0930 \u091f\u093f\u0915\u093e\u090f \u0930\u0916\u0947\u0902 \u0914\u0930 \u0905\u0917\u0932\u0940 \u0938\u0902\u0916\u094d\u092f\u093e \u0915\u094b \u0907\u0927\u0930-\u0909\u0927\u0930 \u092d\u093e\u0917\u0947 \u092c\u093f\u0928\u093e \u092a\u0930\u093f\u0927\u0940\u092f \u0926\u0943\u0937\u094d\u091f\u093f \u0938\u0947 \u0916\u094b\u091c\u0947\u0902\u0964 5\xd75 \u0938\u0947 \u0936\u0941\u0930\u0942 \u0915\u0930\u0947\u0902; \u0905\u0917\u0930 \u0938\u091f\u0940\u0915\u0924\u093e \u0917\u093f\u0930\u0947 \u0924\u092d\u0940 \u0906\u0938\u093e\u0928 \u0917\u094d\u0930\u093f\u0921 \u092a\u0930 \u0909\u0924\u0930\u0947\u0902, \u0914\u0930 \u091c\u092c \u090f\u0915 \u092c\u094b\u0930\u094d\u0921 \u0932\u0917\u092d\u0917 40 \u0938\u0947\u0915\u0902\u0921 \u0938\u0947 \u0915\u092e \u092e\u0947\u0902 \u092a\u0942\u0930\u093e \u0939\u094b\u0928\u0947 \u0932\u0917\u0947 \u0924\u094b 7\xd77 \u0924\u0915 \u092c\u0922\u093c\u0947\u0902\u0964",duration:"\u091b\u094b\u091f\u0947 \u092a\u0930 \u0928\u093f\u092f\u092e\u093f\u0924 \u0938\u0924\u094d\u0930 \u0939\u0940 \u092b\u093e\u092f\u0926\u0947\u092e\u0902\u0926 \u0939\u0948\u0902: \u0930\u094b\u091c\u093c 5\u201310 \u092e\u093f\u0928\u091f, \u090f\u0915 \u092f\u093e \u0926\u094b \u092c\u094b\u0930\u094d\u0921\u0964 \u091c\u093c\u094d\u092f\u093e\u0926\u093e\u0924\u0930 \u0932\u094b\u0917 \u092a\u0939\u0932\u0947 2\u20133 \u0939\u092b\u093c\u094d\u0924\u094b\u0902 \u092e\u0947\u0902 \u0905\u092a\u0928\u093e \u092a\u094d\u0930\u0924\u093f-\u092c\u094b\u0930\u094d\u0921 \u0938\u092e\u092f \u0918\u091f\u0924\u093e \u0926\u0947\u0916\u0924\u0947 \u0939\u0948\u0902, \u092b\u093f\u0930 \u0935\u0939 \u090f\u0915 \u0938\u094d\u0924\u0930 \u092a\u0930 \u0920\u0939\u0930 \u091c\u093e\u0924\u093e \u0939\u0948\u0964",research:"\u091c\u093f\u0938\u0915\u0940 \u0905\u092a\u0947\u0915\u094d\u0937\u093e \u0939\u0948, \u092a\u094d\u0930\u092e\u093e\u0923 \u0920\u0940\u0915 \u0909\u0938\u0940 \u0915\u0947 \u0932\u093f\u090f \u0938\u092c\u0938\u0947 \u092e\u091c\u093c\u092c\u0942\u0924 \u0939\u0948\u0902 \u2014 \u0926\u0943\u0936\u094d\u092f \u0916\u094b\u091c \u092e\u0947\u0902 \u0906\u092a \u0924\u0947\u091c\u093c \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902 \u0914\u0930 \u0906\u092a\u0915\u0940 \u0909\u092a\u092f\u094b\u0917\u0940 \u0926\u0943\u0937\u094d\u091f\u093f-\u092a\u0930\u093f\u0927\u093f \u091a\u094c\u0921\u093c\u0940 \u0939\u094b\u0924\u0940 \u0939\u0948\u0964 \u092f\u0939 \u0926\u093e\u0935\u0947 \u0915\u093f \u0907\u0938\u0938\u0947 \u092a\u0922\u093c\u0928\u0947 \u0915\u0940 \u0917\u0924\u093f \u092f\u093e \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u092c\u0941\u0926\u094d\u0927\u093f \u092c\u0922\u093c\u0924\u0940 \u0939\u0948, \u0915\u092e\u091c\u093c\u094b\u0930 \u0939\u0948\u0902 \u0914\u0930 \u0907\u0938 \u092a\u0930 \u092c\u0939\u0941\u0924 \u0928\u093f\u0930\u094d\u092d\u0930 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902 \u0915\u093f \u0906\u092a \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0948\u0938\u0947 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902, \u0907\u0938\u0932\u093f\u090f \u092c\u0921\u093c\u0947-\u092c\u0921\u093c\u0947 \u0935\u093e\u0926\u094b\u0902 \u0915\u094b \u0938\u093e\u0935\u0927\u093e\u0928\u0940 \u0938\u0947 \u0932\u0947\u0902\u0964",rec:"\u0907\u0938\u0947 \u0915\u0947\u0902\u0926\u094d\u0930\u093f\u0924 \u0915\u093e\u092e \u0938\u0947 \u092a\u0939\u0932\u0947 5 \u092e\u093f\u0928\u091f \u0915\u0947 \u0935\u093e\u0930\u094d\u092e-\u0905\u092a \u0915\u0940 \u0924\u0930\u0939 \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0915\u0930\u0947\u0902\u0964 \u0915\u093f\u0938\u0940 \u0914\u0930 \u0915\u0947 \u0928\u0939\u0940\u0902, \u0905\u092a\u0928\u0947 \u0939\u0940 \u0938\u092c\u0938\u0947 \u0905\u091a\u094d\u091b\u0947 \u0938\u092e\u092f \u0915\u093e \u092a\u0940\u091b\u093e \u0915\u0930\u0947\u0902, \u0914\u0930 \u091c\u092c \u0924\u0915 \u0906\u092a \u0938\u091f\u0940\u0915 \u0939\u0948\u0902 \u0924\u092d\u0940 \u0938\u0924\u094d\u0930 \u0916\u0924\u094d\u092e \u0915\u0930 \u0926\u0947\u0902\u0964",faq:[["\u0915\u094d\u092f\u093e \u092f\u0939 \u0938\u091a\u092e\u0941\u091a \u092a\u0922\u093c\u0928\u0947 \u0915\u0940 \u0930\u092b\u093c\u094d\u0924\u093e\u0930 \u092c\u0922\u093c\u093e\u0924\u093e \u0939\u0948?","\u092f\u0939 \u092a\u0922\u093c\u0928\u0947 \u092e\u0947\u0902 \u0915\u093e\u092e \u0906\u0928\u0947 \u0935\u093e\u0932\u0940 \u0928\u091c\u093c\u0930-\u091f\u093f\u0915\u093e\u0928\u0947 \u0914\u0930 \u092a\u0930\u093f\u0927\u0940\u092f \u0926\u0943\u0937\u094d\u091f\u093f \u0915\u0940 \u0915\u0941\u0936\u0932\u0924\u093e\u0913\u0902 \u0915\u094b \u0938\u093e\u0927\u0924\u093e \u0939\u0948, \u092a\u0930 \u0924\u0947\u091c\u093c \u092a\u0922\u093c\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0936\u092c\u094d\u0926\u092d\u0902\u0921\u093e\u0930 \u0914\u0930 \u0938\u092e\u091d \u092a\u0930 \u092d\u0940 \u0915\u093e\u092e \u091a\u093e\u0939\u093f\u090f \u2014 \u092f\u0939 \u091f\u0947\u092c\u0932 \u090f\u0915 \u0939\u093f\u0938\u094d\u0938\u093e \u0939\u0948, \u0915\u094b\u0908 \u091c\u093e\u0926\u0941\u0908 \u0938\u094d\u0935\u093f\u091a \u0928\u0939\u0940\u0902\u0964"],["\u092e\u0941\u091d\u0947 \u0915\u093f\u0938 \u0906\u0915\u093e\u0930 \u0915\u0940 \u0917\u094d\u0930\u093f\u0921 \u0938\u0947 \u0936\u0941\u0930\u0942 \u0915\u0930\u0928\u093e \u091a\u093e\u0939\u093f\u090f?","5\xd75 \u0938\u0947\u0964 6\xd76 \u092f\u093e 7\xd77 \u092a\u0930 \u0924\u092d\u0940 \u092c\u0922\u093c\u0947\u0902 \u091c\u092c \u090f\u0915 \u092c\u094b\u0930\u094d\u0921 \u0932\u0917\u093e\u0924\u093e\u0930 \u0932\u0917\u092d\u0917 40 \u0938\u0947\u0915\u0902\u0921 \u0938\u0947 \u0915\u092e \u092e\u0947\u0902 \u092a\u0942\u0930\u093e \u0939\u094b\u0928\u0947 \u0932\u0917\u0947\u0964"],["\u092e\u0941\u091d\u0947 \u0915\u093f\u0924\u0928\u0940 \u092c\u093e\u0930 \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0930\u0928\u093e \u091a\u093e\u0939\u093f\u090f?","\u0930\u094b\u091c\u093c, \u0915\u0941\u091b \u092e\u093f\u0928\u091f\u0964 \u0932\u0902\u092c\u0947 \u0938\u0924\u094d\u0930\u094b\u0902 \u0938\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u092c\u093e\u0930-\u092c\u093e\u0930 \u0939\u094b\u0928\u093e \u092e\u093e\u092f\u0928\u0947 \u0930\u0916\u0924\u093e \u0939\u0948\u0964"]],variants:"\u092c\u0921\u093c\u0940 \u0917\u094d\u0930\u093f\u0921 (6\xd76, 7\xd77); \u0930\u0902\u0917-\u0914\u0930-\u0938\u0902\u0916\u094d\u092f\u093e \u0935\u093e\u0932\u0940 \u0917\u094b\u0930\u092c\u094b\u0935\u2013\u0936\u0941\u0932\u094d\u0924\u0947 \u091f\u0947\u092c\u0932, \u091c\u093f\u0938\u092e\u0947\u0902 \u0906\u092a \u0926\u094b \u0915\u094d\u0930\u092e\u094b\u0902 \u0915\u0947 \u092c\u0940\u091a \u092c\u093e\u0930\u0940-\u092c\u093e\u0930\u0940 \u091a\u0932\u0924\u0947 \u0939\u0948\u0902; \u0914\u0930 \u0905\u0915\u094d\u0937\u0930 \u092f\u093e \u091a\u093f\u0939\u094d\u0928 \u0935\u093e\u0932\u0947 \u0938\u0902\u0938\u094d\u0915\u0930\u0923\u0964"},zh:{about:"\u8212\u5c14\u7279\u8868\u662f\u4e00\u4e2a\u7531\u968f\u673a\u6392\u5217\u7684\u6570\u5b57\u7ec4\u6210\u7684\u65b9\u683c\uff08\u901a\u5e38\u4e3a 5\xd75\uff09\u3002\u4f60\u7684\u4efb\u52a1\u662f\u5728\u4fdd\u6301\u89c6\u7ebf\u56fa\u5b9a\u4e8e\u4e2d\u5fc3\u9644\u8fd1\u7684\u540c\u65f6\uff0c\u5c3d\u53ef\u80fd\u5feb\u5730\u6309 1 \u5230 N \u7684\u987a\u5e8f\u627e\u5230\u5e76\u70b9\u6309\u5b83\u4eec\u3002",benefit:"\u89c6\u89c9\u641c\u7d22\u7684\u901f\u5ea6\u3001\u5468\u8fb9\u89c6\u91ce\u7684\u5bbd\u5ea6\u3001\u6301\u7eed\u7684\u6ce8\u610f\u529b\uff0c\u4ee5\u53ca\u652f\u6491\u5feb\u901f\u9605\u8bfb\u7684\u89c6\u7ebf\u56fa\u5b9a\u63a7\u5236\u80fd\u529b\u3002",history:"\u5b83\u5728 20 \u4e16\u7eaa 50 \u5e74\u4ee3\u4f5c\u4e3a\u4e00\u79cd\u68c0\u67e5\u6ce8\u610f\u529b\u7684\u4e34\u5e8a\u5de5\u5177\u88ab\u8bbe\u8ba1\u51fa\u6765\uff0c\u540e\u6765\u8fdb\u5165\u6559\u80b2\u548c\u901f\u8bfb\u8bfe\u7a0b\u9886\u57df\u3002\u5728\u4fc4\u8bed\u56fd\u5bb6\uff0c\u5b83\u662f\u6700\u5e7f\u4e3a\u4eba\u77e5\u7684\u4e13\u6ce8\u529b\u7ec3\u4e60\u4e4b\u4e00\u3002",creator:"\u7531\u5fb7\u56fd\u7cbe\u795e\u75c5\u5b66\u5bb6\u74e6\u5c14\u7279\xb7\u8212\u5c14\u7279\uff08Walter Schulte\uff09\u4e8e 20 \u4e16\u7eaa 50 \u5e74\u4ee3\u8bbe\u8ba1\uff0c\u6700\u521d\u662f\u4e00\u9879\u7528\u4e8e\u8bca\u65ad\u6ce8\u610f\u529b\u548c\u5de5\u4f5c\u80fd\u529b\u969c\u788d\u7684\u5fc3\u7406\u6d4b\u9a8c\u3002",methods:"\u628a\u89c6\u7ebf\u505c\u5728\u4e2d\u5fc3\u683c\u4e0a\uff0c\u7528\u5468\u8fb9\u89c6\u89c9\u53bb\u5b9a\u4f4d\u4e0b\u4e00\u4e2a\u6570\u5b57\uff0c\u800c\u4e0d\u662f\u8ba9\u773c\u775b\u56db\u5904\u4e71\u8df3\u3002\u4ece 5\xd75 \u5f00\u59cb\uff1b\u53ea\u6709\u5728\u51c6\u786e\u7387\u4e0b\u6ed1\u65f6\u624d\u6362\u6210\u66f4\u7b80\u5355\u7684\u65b9\u683c\uff0c\u800c\u4e00\u65e6\u5b8c\u6210\u4e00\u5f20\u8868\u7684\u7528\u65f6\u4f4e\u4e8e\u7ea6 40 \u79d2\uff0c\u5c31\u5347\u5230 7\xd77\u3002",duration:"\u77ed\u800c\u89c4\u5f8b\u624d\u6709\u6548\uff1a\u6bcf\u5929 5 \u5230 10 \u5206\u949f\uff0c\u4e00\u4e24\u5f20\u8868\u5373\u53ef\u3002\u591a\u6570\u4eba\u5728\u5934 2 \u5230 3 \u5468\u91cc\u4f1a\u770b\u5230\u6bcf\u5f20\u8868\u7684\u7528\u65f6\u4e0b\u964d\uff0c\u4e4b\u540e\u8fdb\u5165\u5e73\u53f0\u671f\u3002",research:"\u8bc1\u636e\u6700\u5145\u5206\u7684\u6070\u6070\u662f\u4f60\u80fd\u9884\u6599\u5230\u7684\u90e8\u5206\u2014\u2014\u4f60\u7684\u89c6\u89c9\u641c\u7d22\u4f1a\u53d8\u5feb\uff0c\u6709\u6548\u89c6\u91ce\u4f1a\u53d8\u5bbd\u3002\u81f3\u4e8e\u5b83\u80fd\u63d0\u5347\u9605\u8bfb\u901f\u5ea6\u6216\u6574\u4f53\u667a\u529b\u7684\u8bf4\u6cd5\u5219\u8981\u8584\u5f31\u5f97\u591a\uff0c\u4e14\u9ad8\u5ea6\u4f9d\u8d56\u4f60\u7684\u7ec3\u4e60\u65b9\u5f0f\uff0c\u6240\u4ee5\u5bf9\u90a3\u4e9b\u5b8f\u5927\u627f\u8bfa\u8981\u4fdd\u6301\u8c28\u614e\u3002",rec:"\u628a\u5b83\u5f53\u4f5c\u4e13\u6ce8\u5de5\u4f5c\u524d 5 \u5206\u949f\u7684\u70ed\u8eab\u3002\u8ffd\u81ea\u5df1\u7684\u6700\u597d\u6210\u7ee9\uff0c\u800c\u4e0d\u662f\u522b\u4eba\u7684\uff1b\u5728\u4f60\u8fd8\u80fd\u4fdd\u6301\u51c6\u786e\u7684\u65f6\u5019\u5c31\u7ed3\u675f\u8fd9\u4e00\u8f6e\u3002",faq:[["\u5b83\u771f\u7684\u80fd\u52a0\u5feb\u9605\u8bfb\u901f\u5ea6\u5417\uff1f","\u5b83\u8bad\u7ec3\u7684\u662f\u9605\u8bfb\u6240\u7528\u5230\u7684\u89c6\u7ebf\u56fa\u5b9a\u548c\u5468\u8fb9\u89c6\u89c9\u6280\u80fd\uff0c\u4f46\u66f4\u5feb\u7684\u9605\u8bfb\u540c\u6837\u9700\u8981\u8bcd\u6c47\u548c\u7406\u89e3\u529b\u7684\u8bad\u7ec3\u2014\u2014\u8fd9\u5f20\u8868\u53ea\u662f\u5176\u4e2d\u4e00\u73af\uff0c\u800c\u975e\u4e00\u952e\u89c1\u6548\u7684\u6cd5\u5b9d\u3002"],["\u6211\u8be5\u4ece\u591a\u5927\u7684\u65b9\u683c\u5f00\u59cb\uff1f","5\xd75\u3002\u53ea\u6709\u5f53\u4f60\u80fd\u7a33\u5b9a\u5730\u5728\u7ea6 40 \u79d2\u5185\u5b8c\u6210\u4e00\u5f20\u8868\u65f6\uff0c\u518d\u6362\u5230 6\xd76 \u6216 7\xd77\u3002"],["\u6211\u5e94\u8be5\u591a\u4e45\u7ec3\u4e00\u6b21\uff1f","\u6bcf\u5929\u51e0\u5206\u949f\u3002\u9891\u7387\u6bd4\u5355\u6b21\u957f\u65f6\u95f4\u7ec3\u4e60\u66f4\u91cd\u8981\u3002"]],variants:"\u66f4\u5927\u7684\u65b9\u683c\uff086\xd76\u30017\xd77\uff09\uff1b\u9700\u8981\u4ea4\u66ff\u8fdb\u884c\u4e24\u7ec4\u5e8f\u5217\u7684\u6208\u5c14\u535a\u592b-\u8212\u5c14\u7279\u5f69\u8272\u6570\u5b57\u8868\uff1b\u4ee5\u53ca\u5b57\u6bcd\u6216\u7b26\u53f7\u7248\u672c\u3002"}},sdmt:{ru:{about:"\u0412 SDMT \u043f\u0435\u0440\u0435\u0434 \u0432\u0430\u043c\u0438 \u043a\u043b\u044e\u0447, \u0433\u0434\u0435 \u0434\u0435\u0432\u044f\u0442\u044c \u0430\u0431\u0441\u0442\u0440\u0430\u043a\u0442\u043d\u044b\u0445 \u0441\u0438\u043c\u0432\u043e\u043b\u043e\u0432 \u0441\u043e\u043f\u043e\u0441\u0442\u0430\u0432\u043b\u0435\u043d\u044b \u0446\u0438\u0444\u0440\u0430\u043c \u043e\u0442 1 \u0434\u043e 9. \u0414\u0430\u043b\u044c\u0448\u0435 \u0438\u0434\u0451\u0442 \u0440\u044f\u0434 \u0441\u0438\u043c\u0432\u043e\u043b\u043e\u0432, \u0438 \u043d\u0443\u0436\u043d\u043e \u0432\u043f\u0438\u0441\u044b\u0432\u0430\u0442\u044c \u0446\u0438\u0444\u0440\u0443, \u043a\u043e\u0442\u043e\u0440\u0430\u044f \u0441\u043e\u043e\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0443\u0435\u0442 \u043a\u0430\u0436\u0434\u043e\u043c\u0443, \u0443\u0441\u043f\u0435\u0432 \u043a\u0430\u043a \u043c\u043e\u0436\u043d\u043e \u0431\u043e\u043b\u044c\u0448\u0435 \u0434\u043e \u043a\u043e\u043d\u0446\u0430 \u0442\u0430\u0439\u043c\u0435\u0440\u0430. \u041f\u0440\u0430\u0432\u0438\u043b\u043e \u044d\u043b\u0435\u043c\u0435\u043d\u0442\u0430\u0440\u043d\u043e\u0435, \u043d\u043e \u043f\u0440\u0438\u043c\u0435\u043d\u044f\u0442\u044c \u0435\u0433\u043e \u043f\u0440\u0438\u0445\u043e\u0434\u0438\u0442\u0441\u044f \u0441\u043d\u043e\u0432\u0430 \u0438 \u0441\u043d\u043e\u0432\u0430, \u043d\u0435 \u0441\u0431\u0430\u0432\u043b\u044f\u044f \u0442\u0435\u043c\u043f\u0430.",benefit:"\u0422\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442\u0441\u044f \u043f\u0440\u0435\u0436\u0434\u0435 \u0432\u0441\u0435\u0433\u043e \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u043e\u0431\u0440\u0430\u0431\u043e\u0442\u043a\u0438 \u0438\u043d\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u0438: \u043a\u0430\u043a \u0431\u044b\u0441\u0442\u0440\u043e \u0432\u044b \u0432\u043e\u0441\u043f\u0440\u0438\u043d\u0438\u043c\u0430\u0435\u0442\u0435 \u0437\u043d\u0430\u043a, \u043d\u0430\u0445\u043e\u0434\u0438\u0442\u0435 \u043d\u0443\u0436\u043d\u044b\u0439 \u043e\u0442\u0432\u0435\u0442 \u0438 \u0440\u0435\u0430\u0433\u0438\u0440\u0443\u0435\u0442\u0435. \u041f\u043e\u0441\u043a\u043e\u043b\u044c\u043a\u0443 \u0432\u0437\u0433\u043b\u044f\u0434 \u043f\u043e\u0441\u0442\u043e\u044f\u043d\u043d\u043e \u0432\u043e\u0437\u0432\u0440\u0430\u0449\u0430\u0435\u0442\u0441\u044f \u043a \u043a\u043b\u044e\u0447\u0443, \u043f\u043e\u0434\u043a\u043b\u044e\u0447\u0430\u044e\u0442\u0441\u044f \u0435\u0449\u0451 \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0439 \u043f\u043e\u0438\u0441\u043a, \u0443\u0441\u0442\u043e\u0439\u0447\u0438\u0432\u043e\u0435 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u0438 \u043d\u0435\u043c\u043d\u043e\u0433\u043e \u043a\u0440\u0430\u0442\u043a\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u043e\u0439 \u043f\u0430\u043c\u044f\u0442\u0438, \u043a\u043e\u0433\u0434\u0430 \u043f\u0430\u0440\u044b \u043d\u0430\u0447\u0438\u043d\u0430\u044e\u0442 \u0434\u0435\u0440\u0436\u0430\u0442\u044c\u0441\u044f \u0432 \u0433\u043e\u043b\u043e\u0432\u0435.",history:"\u0424\u043e\u0440\u043c\u0430\u0442 \u0441\u0438\u043c\u0432\u043e\u043b-\u0446\u0438\u0444\u0440\u0430 \u0432\u044b\u0440\u043e\u0441 \u0438\u0437 \u0437\u0430\u0434\u0430\u043d\u0438\u044f \u043d\u0430 \u043f\u043e\u0434\u0441\u0442\u0430\u043d\u043e\u0432\u043a\u0443, \u043a\u043e\u0442\u043e\u0440\u043e\u0435 \u043f\u0440\u0438\u043c\u0435\u043d\u044f\u043b\u043e\u0441\u044c \u0432 \u0442\u0435\u0441\u0442\u0430\u0445 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442\u0430 \u0441 \u043d\u0430\u0447\u0430\u043b\u0430 XX \u0432\u0435\u043a\u0430, \u0432 \u0442\u043e\u043c \u0447\u0438\u0441\u043b\u0435 \u0432 \u0448\u043a\u0430\u043b\u0430\u0445 \u0412\u0435\u043a\u0441\u043b\u0435\u0440\u0430. \u0412 1960-\u0445 \u0410\u0430\u0440\u043e\u043d \u0421\u043c\u0438\u0442 \u043f\u0435\u0440\u0435\u0434\u0435\u043b\u0430\u043b \u0435\u0433\u043e \u0442\u0430\u043a, \u0447\u0442\u043e\u0431\u044b \u0447\u0435\u043b\u043e\u0432\u0435\u043a \u043d\u0430\u0437\u044b\u0432\u0430\u043b \u0438\u043b\u0438 \u043f\u0438\u0441\u0430\u043b \u0446\u0438\u0444\u0440\u0443, \u0430 \u043d\u0435 \u0440\u0438\u0441\u043e\u0432\u0430\u043b \u0441\u0438\u043c\u0432\u043e\u043b, \u0438 \u0442\u0435\u0441\u0442 \u0441\u0442\u0430\u043b \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u0438 \u043f\u043e\u0447\u0442\u0438 \u043d\u0435 \u0437\u0430\u0432\u0438\u0441\u0435\u043b \u043e\u0442 \u044f\u0437\u044b\u043a\u0430. \u041f\u043e\u0441\u043b\u0435 \u043f\u0443\u0431\u043b\u0438\u043a\u0430\u0446\u0438\u0438 \u0432 1973 \u0433\u043e\u0434\u0443 SDMT \u0440\u0430\u0437\u043e\u0448\u0451\u043b\u0441\u044f \u043f\u043e \u043d\u0435\u0439\u0440\u043e\u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u0438, \u0430 \u0441 1990-\u0445 \u0441\u0442\u0430\u043b \u0441\u0442\u0430\u043d\u0434\u0430\u0440\u0442\u043d\u043e\u0439 \u043c\u0435\u0440\u043e\u0439 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u0438 \u043c\u044b\u0448\u043b\u0435\u043d\u0438\u044f \u0432 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u044f\u0445 \u0440\u0430\u0441\u0441\u0435\u044f\u043d\u043d\u043e\u0433\u043e \u0441\u043a\u043b\u0435\u0440\u043e\u0437\u0430.",creator:"\u0422\u0435\u0441\u0442 \u0441\u043e\u0437\u0434\u0430\u043b \u0430\u043c\u0435\u0440\u0438\u043a\u0430\u043d\u0441\u043a\u0438\u0439 \u043d\u0435\u0439\u0440\u043e\u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433 \u0410\u0430\u0440\u043e\u043d \u0421\u043c\u0438\u0442: \u043e\u043d \u043e\u0431\u043a\u0430\u0442\u044b\u0432\u0430\u043b \u043c\u0435\u0442\u043e\u0434\u0438\u043a\u0443 \u0432 1960-\u0445 \u0438 \u043e\u0444\u0438\u0446\u0438\u0430\u043b\u044c\u043d\u043e \u043e\u043f\u0443\u0431\u043b\u0438\u043a\u043e\u0432\u0430\u043b \u0435\u0451 \u0432 1973 \u0433\u043e\u0434\u0443 \u0447\u0435\u0440\u0435\u0437 \u0438\u0437\u0434\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432\u043e Western Psychological Services \u0432 \u041b\u043e\u0441-\u0410\u043d\u0434\u0436\u0435\u043b\u0435\u0441\u0435. \u0421\u0430\u043c\u0430 \u0438\u0434\u0435\u044f \u043f\u043e\u0434\u0441\u0442\u0430\u043d\u043e\u0432\u043a\u0438 \u0441\u0442\u0430\u0440\u0448\u0435 \u0438 \u043f\u0440\u0438\u0434\u0443\u043c\u0430\u043d\u0430 \u043d\u0435 \u0438\u043c, \u043d\u043e \u0438\u043c\u0435\u043d\u043d\u043e \u0432\u0435\u0440\u0441\u0438\u044f \xab\u0441\u0438\u043c\u0432\u043e\u043b \u0432 \u0446\u0438\u0444\u0440\u0443\xbb \u043f\u0440\u0438\u043d\u0430\u0434\u043b\u0435\u0436\u0438\u0442 \u0421\u043c\u0438\u0442\u0443.",methods:"\u0417\u0430\u043f\u043e\u043c\u0438\u043d\u0430\u0439\u0442\u0435 \u043a\u043b\u044e\u0447 \u043a\u0430\u043a \u043c\u043e\u0436\u043d\u043e \u0440\u0430\u043d\u044c\u0448\u0435, \u0447\u0442\u043e\u0431\u044b \u043f\u0435\u0440\u0435\u0441\u0442\u0430\u0442\u044c \u043d\u0430 \u043d\u0435\u0433\u043e \u0441\u043c\u043e\u0442\u0440\u0435\u0442\u044c: \u043f\u0435\u0440\u0432\u044b\u0435 \u0432\u044b\u0443\u0447\u0435\u043d\u043d\u044b\u0435 \u043f\u0430\u0440\u044b \u0434\u0430\u044e\u0442 \u0441\u0430\u043c\u044b\u0439 \u0437\u0430\u043c\u0435\u0442\u043d\u044b\u0439 \u043f\u0440\u0438\u0440\u043e\u0441\u0442 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u0438. \u0414\u0435\u0440\u0436\u0438\u0442\u0435 \u0440\u043e\u0432\u043d\u044b\u0439 \u0440\u0438\u0442\u043c \u0441\u043b\u0435\u0432\u0430 \u043d\u0430\u043f\u0440\u0430\u0432\u043e, \u0430 \u043d\u0435 \u0440\u0432\u0438\u0442\u0435\u0441\u044c \u0438 \u0437\u0430\u0441\u0442\u0440\u0435\u0432\u0430\u0439\u0442\u0435, \u0438 \u043d\u0435 \u043f\u0435\u0440\u0435\u043f\u0440\u043e\u0432\u0435\u0440\u044f\u0439\u0442\u0435 \u043e\u0442\u0432\u0435\u0442\u044b, \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u0438 \u0442\u0430\u043a \u0437\u043d\u0430\u0435\u0442\u0435. \u0415\u0441\u043b\u0438 \u043f\u0430\u0440\u0430 \u0432\u044b\u043f\u0430\u043b\u0430 \u0438\u0437 \u043f\u0430\u043c\u044f\u0442\u0438, \u043e\u0441\u043e\u0437\u043d\u0430\u043d\u043d\u043e \u0437\u0430\u0444\u0438\u043a\u0441\u0438\u0440\u0443\u0439\u0442\u0435 \u0435\u0451 \u0437\u0430\u043d\u043e\u0432\u043e, \u0430 \u043d\u0435 \u0433\u0430\u0434\u0430\u0439\u0442\u0435 \u0440\u0430\u0437 \u0437\u0430 \u0440\u0430\u0437\u043e\u043c.",duration:"\u041b\u0443\u0447\u0448\u0435 \u0432\u0441\u0435\u0433\u043e \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u0435 \u043f\u043e\u0434\u0445\u043e\u0434\u044b: \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0440\u0430\u0443\u043d\u0434\u043e\u0432 \u043f\u043e \u043e\u0434\u043d\u043e\u0439-\u0434\u0432\u0435 \u043c\u0438\u043d\u0443\u0442\u044b, \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0434\u043d\u0435\u0439 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e. \u0417\u0430\u0434\u0430\u043d\u0438\u0435 \u0438\u0437\u043c\u0430\u0442\u044b\u0432\u0430\u0435\u0442 \u0433\u043e\u043b\u043e\u0432\u0443, \u0438 \u043a\u0430\u0447\u0435\u0441\u0442\u0432\u043e \u043f\u0430\u0434\u0430\u0435\u0442 \u0431\u044b\u0441\u0442\u0440\u043e, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u043e\u0441\u0442\u0430\u043d\u0430\u0432\u043b\u0438\u0432\u0430\u0439\u0442\u0435\u0441\u044c, \u043a\u043e\u0433\u0434\u0430 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u0432 \u0440\u0430\u043c\u043a\u0430\u0445 \u0441\u0435\u0441\u0441\u0438\u0438 \u0432\u044b\u0445\u043e\u0434\u0438\u0442 \u043d\u0430 \u043f\u043b\u0430\u0442\u043e, \u0430 \u043d\u0435 \u043f\u0440\u043e\u0434\u043e\u043b\u0436\u0430\u0439\u0442\u0435 \u0447\u0435\u0440\u0435\u0437 \u0441\u0438\u043b\u0443.",research:"\u041d\u0430\u0434\u0451\u0436\u043d\u0435\u0435 \u0432\u0441\u0435\u0433\u043e \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043d\u043e \u0440\u043e\u0432\u043d\u043e \u0442\u043e, \u0447\u0435\u0433\u043e \u0438 \u0436\u0434\u0451\u0448\u044c: \u0432\u044b \u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u0435\u0441\u044c \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u0438\u043c\u0435\u043d\u043d\u043e \u0432 \u043f\u043e\u0434\u0441\u0442\u0430\u043d\u043e\u0432\u043a\u0435 \u0441\u0438\u043c\u0432\u043e\u043b-\u0446\u0438\u0444\u0440\u0430, \u0430 \u043a\u043b\u0438\u043d\u0438\u0447\u0435\u0441\u043a\u0430\u044f \u0432\u0435\u0440\u0441\u0438\u044f \u0441\u0442\u0430\u0431\u0438\u043b\u044c\u043d\u043e \u043e\u0442\u0441\u043b\u0435\u0436\u0438\u0432\u0430\u0435\u0442 \u0438\u0437\u043c\u0435\u043d\u0435\u043d\u0438\u044f \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u0438 \u043e\u0431\u0440\u0430\u0431\u043e\u0442\u043a\u0438 \u043f\u0440\u0438 \u0442\u0430\u043a\u0438\u0445 \u0441\u043e\u0441\u0442\u043e\u044f\u043d\u0438\u044f\u0445, \u043a\u0430\u043a \u0440\u0430\u0441\u0441\u0435\u044f\u043d\u043d\u044b\u0439 \u0441\u043a\u043b\u0435\u0440\u043e\u0437. \u0410 \u0432\u043e\u0442 \u0448\u0438\u0440\u043e\u043a\u0438\u0439 \u043f\u0435\u0440\u0435\u043d\u043e\u0441 \u043d\u0435 \u0434\u043e\u043a\u0430\u0437\u0430\u043d: \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0430 \u043d\u0435 \u0434\u0435\u043b\u0430\u0435\u0442 \u043d\u0430\u0434\u0451\u0436\u043d\u043e \u043b\u0443\u0447\u0448\u0435 \u043d\u0435\u0441\u0432\u044f\u0437\u0430\u043d\u043d\u043e\u0435 \u043c\u044b\u0448\u043b\u0435\u043d\u0438\u0435, \u043f\u0430\u043c\u044f\u0442\u044c \u0438\u043b\u0438 \u043e\u0431\u0449\u0438\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442, \u0438 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u0438 \u043f\u043e\u0434\u0447\u0451\u0440\u043a\u0438\u0432\u0430\u044e\u0442, \u0447\u0442\u043e \u0442\u0435\u0441\u0442 \u043d\u0435 \xab\u0447\u0438\u0441\u0442\u044b\u0439\xbb, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u043f\u0440\u0438\u0440\u043e\u0441\u0442 \u043c\u043e\u0436\u0435\u0442 \u0438\u0434\u0442\u0438 \u043e\u0442 \u0437\u0430\u0443\u0447\u0438\u0432\u0430\u043d\u0438\u044f \u043a\u043b\u044e\u0447\u0430 \u043d\u0435 \u043c\u0435\u043d\u044c\u0448\u0435, \u0447\u0435\u043c \u043e\u0442 \u0443\u0441\u043a\u043e\u0440\u0435\u043d\u0438\u044f \u043e\u0431\u0440\u0430\u0431\u043e\u0442\u043a\u0438. \u0421\u0447\u0438\u0442\u0430\u0439\u0442\u0435 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442 \u043c\u0435\u0440\u043e\u0439 \u044d\u0442\u043e\u0433\u043e \u043d\u0430\u0432\u044b\u043a\u0430, \u0430 \u043d\u0435 \u0434\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432\u043e\u043c \u043f\u043e\u0443\u043c\u043d\u0435\u043d\u0438\u044f \u0432 \u0446\u0435\u043b\u043e\u043c.",rec:"\u0412\u044b\u0443\u0447\u0438\u0442\u0435 \u043a\u043b\u044e\u0447 \u0437\u0430 \u043f\u0435\u0440\u0432\u044b\u0435 \u0434\u0435\u0441\u044f\u0442\u044c \u0441\u0435\u043a\u0443\u043d\u0434 \u0438 \u0434\u0435\u0440\u0436\u0438\u0442\u0435 \u043f\u043b\u0430\u0432\u043d\u044b\u0439 \u043d\u0435\u043f\u0440\u0435\u0440\u044b\u0432\u043d\u044b\u0439 \u0442\u0435\u043c\u043f: \u0442\u0435, \u043a\u0442\u043e \u043e\u0441\u0442\u0430\u043d\u0430\u0432\u043b\u0438\u0432\u0430\u0435\u0442\u0441\u044f \u043f\u0435\u0440\u0435\u043f\u0440\u043e\u0432\u0435\u0440\u044f\u0442\u044c, \u0442\u0435\u0440\u044f\u044e\u0442 \u0431\u043e\u043b\u044c\u0448\u0435 \u0432\u0440\u0435\u043c\u0435\u043d\u0438, \u0447\u0435\u043c \u0441\u0442\u043e\u0438\u043b\u0438 \u0431\u044b \u043f\u0430\u0440\u0430 \u043e\u0448\u0438\u0431\u043e\u043a.",faq:[["\u042d\u0442\u043e \u0442\u043e \u0436\u0435 \u0441\u0430\u043c\u043e\u0435, \u0447\u0442\u043e \u0442\u0435\u0441\u0442 \u043d\u0430 \u043f\u0430\u043c\u044f\u0442\u044c?","\u041d\u0435 \u0441\u043e\u0432\u0441\u0435\u043c. \u041f\u0430\u043c\u044f\u0442\u044c \u043f\u043e\u043c\u043e\u0433\u0430\u0435\u0442, \u043a\u043e\u0433\u0434\u0430 \u043a\u043b\u044e\u0447 \u0443\u0436\u0435 \u0432\u044b\u0443\u0447\u0435\u043d, \u043d\u043e \u043e\u0441\u043d\u043e\u0432\u0430 \u0437\u0430\u0434\u0430\u043d\u0438\u044f \u2014 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u0441\u043e\u043f\u043e\u0441\u0442\u0430\u0432\u043b\u0435\u043d\u0438\u044f, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u043e\u043d \u0431\u043b\u0438\u0436\u0435 \u043a \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044e \u0438 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u0438 \u043e\u0431\u0440\u0430\u0431\u043e\u0442\u043a\u0438, \u0447\u0435\u043c \u043a \u043f\u0430\u043c\u044f\u0442\u0438."],["\u041f\u043e\u0447\u0435\u043c\u0443 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442 \u0442\u0430\u043a \u0441\u043a\u0430\u0447\u0435\u0442 \u043e\u0442 \u0440\u0430\u0443\u043d\u0434\u0430 \u043a \u0440\u0430\u0443\u043d\u0434\u0443?","\u041a\u043e\u0440\u043e\u0442\u043a\u0438\u0435 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u043d\u044b\u0435 \u0437\u0430\u0434\u0430\u043d\u0438\u044f \u043d\u0430 \u0432\u0440\u0435\u043c\u044f \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043d\u043d\u043e \u043d\u0435\u0441\u0442\u0430\u0431\u0438\u043b\u044c\u043d\u044b, \u0438 \u043c\u043d\u043e\u0433\u043e\u0435 \u0437\u0430\u0432\u0438\u0441\u0438\u0442 \u043e\u0442 \u0442\u043e\u0433\u043e, \u043d\u0430\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0445\u043e\u0440\u043e\u0448\u043e \u0432\u044b \u043f\u043e\u043c\u043d\u0438\u0442\u0435 \u043a\u043b\u044e\u0447 \u0432 \u044d\u0442\u043e\u0442 \u0437\u0430\u0445\u043e\u0434. \u0421\u043c\u043e\u0442\u0440\u0438\u0442\u0435 \u043d\u0430 \u0441\u0440\u0435\u0434\u043d\u0438\u0439 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442 \u043f\u043e \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u0438\u043c \u0440\u0430\u0443\u043d\u0434\u0430\u043c, \u0430 \u043d\u0435 \u043d\u0430 \u043e\u0442\u0434\u0435\u043b\u044c\u043d\u0443\u044e \u0446\u0438\u0444\u0440\u0443."],["\u0421\u0442\u0430\u043d\u0443 \u043b\u0438 \u044f \u0443\u043c\u043d\u0435\u0435 \u0432 \u0436\u0438\u0437\u043d\u0438, \u0435\u0441\u043b\u0438 \u0431\u0443\u0434\u0443 \u044d\u0442\u043e \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u0430\u0442\u044c?","\u0412\u044b \u0441\u0442\u0430\u043d\u0435\u0442\u0435 \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u0432 \u0442\u0430\u043a\u043e\u0439 \u043f\u043e\u0434\u0441\u0442\u0430\u043d\u043e\u0432\u043a\u0435 \u0438 \u043f\u043e\u0445\u043e\u0436\u0438\u0445 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u043d\u044b\u0445 \u0437\u0430\u0434\u0430\u043d\u0438\u044f\u0445. \u0421\u0435\u0440\u044c\u0451\u0437\u043d\u044b\u0445 \u0434\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432, \u0447\u0442\u043e \u044d\u0442\u043e \u043f\u043e\u0434\u043d\u0438\u043c\u0430\u0435\u0442 \u043e\u0431\u0449\u0438\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0438\u043b\u0438 \u043d\u0435\u0441\u0432\u044f\u0437\u0430\u043d\u043d\u044b\u0435 \u043d\u0430\u0432\u044b\u043a\u0438, \u043c\u0430\u043b\u043e, \u0442\u0430\u043a \u0447\u0442\u043e \u0440\u0430\u0434\u0443\u0439\u0442\u0435\u0441\u044c \u043f\u0440\u043e\u0433\u0440\u0435\u0441\u0441\u0443 \u0437\u0434\u0435\u0441\u044c, \u043d\u043e \u043d\u0435 \u0436\u0434\u0438\u0442\u0435 \u0448\u0438\u0440\u043e\u043a\u043e\u0433\u043e \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0430."]],variants:"\u0415\u0441\u0442\u044c \u0443\u0441\u0442\u043d\u044b\u0439 \u0432\u0430\u0440\u0438\u0430\u043d\u0442, \u0433\u0434\u0435 \u0446\u0438\u0444\u0440\u0443 \u043f\u0440\u043e\u0438\u0437\u043d\u043e\u0441\u044f\u0442 \u0432\u0441\u043b\u0443\u0445, \u0430 \u043d\u0435 \u0432\u043f\u0438\u0441\u044b\u0432\u0430\u044e\u0442, \u2014 \u0432 \u043a\u043b\u0438\u043d\u0438\u043a\u0435 \u0438\u043c \u0443\u0431\u0438\u0440\u0430\u044e\u0442 \u0438\u0437 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442\u0430 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u043f\u0438\u0441\u044c\u043c\u0430, \u0438 \u043f\u0438\u0441\u044c\u043c\u0435\u043d\u043d\u044b\u0439, \u0433\u0434\u0435 \u0446\u0438\u0444\u0440\u044b \u0432\u043f\u0438\u0441\u044b\u0432\u0430\u044e\u0442 \u043e\u0442 \u0440\u0443\u043a\u0438. \u0411\u043b\u0438\u0437\u043a\u0438\u0439 Digit Symbol Substitution Test \u043f\u0435\u0440\u0435\u0432\u043e\u0440\u0430\u0447\u0438\u0432\u0430\u0435\u0442 \u0437\u0430\u0434\u0430\u0447\u0443: \u0442\u0430\u043c \u0440\u0438\u0441\u0443\u044e\u0442 \u0441\u0438\u043c\u0432\u043e\u043b, \u0430 \u043a\u043e\u043c\u043f\u044c\u044e\u0442\u0435\u0440\u043d\u044b\u0435 \u0432\u0435\u0440\u0441\u0438\u0438 \u0434\u043e\u0431\u0430\u0432\u043b\u044f\u044e\u0442 \u0441\u043b\u0443\u0447\u0430\u0439\u043d\u044b\u0435 \u043a\u043b\u044e\u0447\u0438 \u0438 \u043d\u0430\u0440\u0430\u0441\u0442\u0430\u044e\u0449\u0443\u044e \u0441\u043b\u043e\u0436\u043d\u043e\u0441\u0442\u044c."},en:{about:"The SDMT shows you a key that pairs nine abstract symbols with the digits 1 to 9. A row of symbols then appears, and your job is to type the matching digit for each one, as many as you can before the timer runs out. It is a pure speed task: the rule is trivial, but you have to apply it again and again without slowing down.",benefit:"It mainly trains processing speed, the rate at which you take in a stimulus, look up the right response and act on it. Because you constantly glance back at the key, it also leans on visual scanning, sustained attention and a bit of short-term memory once you start holding pairs in your head.",history:"The symbol-digit format grew out of the digit-symbol substitution task used in intelligence batteries since the early 20th century, including the Wechsler scales. Aaron Smith reworked it in the 1960s so the person says or writes the digit rather than drawing the symbol, which made it faster and language-light. After its 1973 publication the SDMT spread widely in neuropsychology and, from the 1990s, became a standard measure of cognitive speed in multiple sclerosis research.",creator:"It was created by the American neuropsychologist Aaron Smith, who piloted it through the 1960s and published it formally in 1973 through Western Psychological Services in Los Angeles. The underlying substitution idea is older and not his invention, but this particular symbol-to-digit version is his.",methods:"Burn the key into memory early so you can stop looking back; the first few pairs you memorise give the biggest speed gain. Keep a steady left-to-right rhythm instead of racing and stalling, and resist the urge to double-check answers you already know. If you misremember a pair, re-anchor it deliberately rather than guessing repeatedly.",duration:"Short bouts work best: a few timed rounds of one to two minutes, a handful of days a week. The task is mentally taxing, so quality drops fast once you fatigue; stop when your speed plateaus within a session rather than grinding on.",research:"Evidence is strongest for exactly what you would expect, which is that you get faster at symbol-digit substitution itself, and the clinical version reliably tracks processing-speed changes in conditions like multiple sclerosis. What it does not cleanly show is broad transfer: practising it does not reliably make unrelated thinking, memory or general intelligence better, and researchers stress the test is not process-pure, so improvement can come from memorising the key as much as from faster processing. Treat the score as a measure of this skill, not proof of a sharper mind overall.",rec:"Memorise the key in the first ten seconds, then keep a smooth unbroken pace; the people who pause to verify lose more time than the few errors would have cost.",faq:[["Is this the same as a memory test?","Not really. Memory helps once you learn the key, but the core demand is speed of matching, so it sits closer to attention and processing speed than to memory."],["Why does my score jump around so much between rounds?","Short timed speed tasks are naturally noisy, and how well you remember the key on that run matters a lot. Look at your average over several rounds rather than any single score."],["Will training this make me smarter in everyday life?","It makes you faster at this kind of substitution and similar speeded tasks. There is little solid evidence it lifts general intelligence or unrelated skills, so enjoy the sharpening here without expecting broad spillover."]],variants:"There is an oral version, where you say the digit instead of typing, used clinically to remove handwriting speed from the result, and a written version where you fill the digits in by hand. The closely related Digit Symbol Substitution Test reverses the demand by having you draw the symbol, and computerised editions add randomised keys and rolling difficulty."},es:{about:"El SDMT te muestra una clave que empareja nueve s\xedmbolos abstractos con los d\xedgitos del 1 al 9. Luego aparece una fila de s\xedmbolos y tu tarea es escribir el d\xedgito que le corresponde a cada uno, tantos como puedas antes de que se agote el tiempo. Es una tarea de pura velocidad: la regla es trivial, pero hay que aplicarla una y otra vez sin perder ritmo.",benefit:"Entrena sobre todo la velocidad de procesamiento, es decir, el ritmo al que captas un est\xedmulo, buscas la respuesta correcta y act\xfaas en consecuencia. Como vuelves constantemente la vista a la clave, tambi\xe9n pone a trabajar el rastreo visual, la atenci\xf3n sostenida y algo de memoria a corto plazo en cuanto empiezas a retener pares en la cabeza.",history:"El formato s\xedmbolo-d\xedgito surgi\xf3 de la tarea de sustituci\xf3n d\xedgito-s\xedmbolo empleada en las bater\xedas de inteligencia desde principios del siglo XX, incluidas las escalas Wechsler. Aaron Smith la reformul\xf3 en los a\xf1os sesenta para que la persona dijera o escribiera el d\xedgito en lugar de dibujar el s\xedmbolo, lo que la hizo m\xe1s r\xe1pida y menos dependiente del idioma. Tras su publicaci\xf3n en 1973, el SDMT se extendi\xf3 ampliamente por la neuropsicolog\xeda y, a partir de los a\xf1os noventa, se convirti\xf3 en una medida est\xe1ndar de la velocidad cognitiva en la investigaci\xf3n sobre esclerosis m\xfaltiple.",creator:"Lo cre\xf3 el neuropsic\xf3logo estadounidense Aaron Smith, que lo fue probando a lo largo de los a\xf1os sesenta y lo public\xf3 formalmente en 1973 a trav\xe9s de Western Psychological Services en Los \xc1ngeles. La idea de fondo de la sustituci\xf3n es m\xe1s antigua y no es invenci\xf3n suya, pero esta versi\xf3n concreta de s\xedmbolo a d\xedgito s\xed es obra de \xe9l.",methods:"Gr\xe1bate la clave en la memoria cuanto antes para dejar de mirarla; los primeros pares que memorizas son los que m\xe1s velocidad te aportan. Mant\xe9n un ritmo constante de izquierda a derecha en vez de acelerar y frenar, y resiste la tentaci\xf3n de comprobar dos veces respuestas que ya conoces. Si recuerdas mal un par, vuelve a fijarlo de forma deliberada en lugar de adivinar una y otra vez.",duration:"Lo mejor son las tandas cortas: unas pocas rondas cronometradas de uno a dos minutos, algunos d\xedas a la semana. La tarea exige mucho mentalmente, as\xed que la calidad cae r\xe1pido en cuanto te fatigas; para cuando tu velocidad se estanque dentro de una sesi\xf3n, en vez de seguir machacando.",research:"La evidencia es m\xe1s s\xf3lida justo en lo que cabr\xeda esperar: te vuelves m\xe1s r\xe1pido en la propia sustituci\xf3n s\xedmbolo-d\xedgito, y la versi\xf3n cl\xednica refleja de forma fiable los cambios en la velocidad de procesamiento en condiciones como la esclerosis m\xfaltiple. Lo que no demuestra con claridad es la transferencia amplia: practicarlo no mejora de manera fiable el razonamiento, la memoria o la inteligencia general en tareas no relacionadas, y los investigadores insisten en que la prueba no es pura en cuanto al proceso, de modo que la mejora puede venir tanto de memorizar la clave como de procesar m\xe1s r\xe1pido. Toma la puntuaci\xf3n como una medida de esta habilidad, no como prueba de una mente m\xe1s \xe1gil en general.",rec:"Memoriza la clave en los primeros diez segundos y luego mant\xe9n un ritmo fluido e ininterrumpido; quien se detiene a verificar pierde m\xe1s tiempo del que le habr\xedan costado los pocos errores.",faq:[["\xbfEs esto lo mismo que una prueba de memoria?","En realidad no. La memoria ayuda una vez que aprendes la clave, pero la demanda central es la velocidad de emparejamiento, as\xed que est\xe1 m\xe1s cerca de la atenci\xf3n y la velocidad de procesamiento que de la memoria."],["\xbfPor qu\xe9 mi puntuaci\xf3n var\xeda tanto de una ronda a otra?","Las tareas cronometradas y cortas de velocidad son naturalmente ruidosas, y lo bien que recuerdes la clave en esa ronda concreta influye mucho. F\xedjate en tu media de varias rondas en lugar de en una sola puntuaci\xf3n."],["\xbfEntrenar esto me har\xe1 m\xe1s listo en el d\xeda a d\xeda?","Te hace m\xe1s r\xe1pido en este tipo de sustituci\xf3n y en tareas de velocidad parecidas. Hay poca evidencia s\xf3lida de que eleve la inteligencia general o habilidades no relacionadas, as\xed que disfruta de la mejora aqu\xed sin esperar que se extienda a otros \xe1mbitos."]],variants:"Existe una versi\xf3n oral, en la que dices el d\xedgito en lugar de escribirlo, usada en cl\xednica para eliminar del resultado la velocidad de escritura a mano, y una versi\xf3n escrita en la que rellenas los d\xedgitos a mano. La estrechamente emparentada Prueba de Sustituci\xf3n D\xedgito-S\xedmbolo invierte la demanda al hacerte dibujar el s\xedmbolo, y las ediciones informatizadas a\xf1aden claves aleatorias y dificultad creciente."},de:{about:"Der SDMT zeigt dir eine Legende, die neun abstrakte Symbole den Ziffern 1 bis 9 zuordnet. Anschlie\xdfend erscheint eine Reihe von Symbolen, und deine Aufgabe ist es, zu jedem die passende Ziffer einzutippen \u2013 so viele wie m\xf6glich, bevor die Zeit abl\xe4uft. Es ist eine reine Geschwindigkeitsaufgabe: Die Regel ist banal, aber du musst sie immer wieder anwenden, ohne langsamer zu werden.",benefit:"Trainiert wird vor allem die Verarbeitungsgeschwindigkeit \u2013 das Tempo, mit dem du einen Reiz aufnimmst, die richtige Antwort nachschl\xe4gst und sie umsetzt. Weil du st\xe4ndig zur Legende zur\xfcckschaust, beansprucht die Aufgabe au\xdferdem das visuelle Absuchen, die Daueraufmerksamkeit und ein wenig das Kurzzeitged\xe4chtnis, sobald du anf\xe4ngst, dir Zuordnungen zu merken.",history:"Das Symbol-Ziffer-Format entstand aus der Symbol-Ziffer-Ersetzungsaufgabe, die seit dem fr\xfchen 20. Jahrhundert in Intelligenztest-Batterien verwendet wird, unter anderem in den Wechsler-Skalen. Aaron Smith \xfcberarbeitete sie in den 1960er-Jahren so, dass die Person die Ziffer nennt oder schreibt, statt das Symbol zu zeichnen \u2013 das machte sie schneller und sprachunabh\xe4ngiger. Nach der Ver\xf6ffentlichung 1973 verbreitete sich der SDMT weit in der Neuropsychologie und wurde ab den 1990er-Jahren zu einem Standardma\xdf kognitiver Geschwindigkeit in der Multiple-Sklerose-Forschung.",creator:"Entwickelt wurde er vom amerikanischen Neuropsychologen Aaron Smith, der ihn \xfcber die 1960er-Jahre hinweg erprobte und 1973 formal \xfcber Western Psychological Services in Los Angeles ver\xf6ffentlichte. Die zugrunde liegende Idee der Ersetzungsaufgabe ist \xe4lter und stammt nicht von ihm, aber diese konkrete Symbol-zu-Ziffer-Variante schon.",methods:"Pr\xe4ge dir die Legende fr\xfch ein, damit du nicht mehr zur\xfcckschauen musst; die ersten paar Zuordnungen, die du dir merkst, bringen den gr\xf6\xdften Geschwindigkeitsgewinn. Halte einen gleichm\xe4\xdfigen Rhythmus von links nach rechts, statt zu rasen und dann zu stocken, und widerstehe dem Drang, Antworten doppelt zu pr\xfcfen, die du l\xe4ngst kennst. Wenn du eine Zuordnung falsch erinnerst, verankere sie gezielt neu, statt immer wieder zu raten.",duration:"Kurze Einheiten funktionieren am besten: ein paar Durchg\xe4nge von ein bis zwei Minuten auf Zeit, an einer Handvoll Tage pro Woche. Die Aufgabe ist geistig anstrengend, daher f\xe4llt die Qualit\xe4t schnell ab, sobald du erm\xfcdest; h\xf6r auf, wenn dein Tempo innerhalb einer Sitzung stagniert, statt dich weiterzuqu\xe4len.",research:"Die Belege sind am st\xe4rksten f\xfcr genau das, was man erwarten w\xfcrde: Du wirst schneller in der Symbol-Ziffer-Ersetzung selbst, und die klinische Version bildet Ver\xe4nderungen der Verarbeitungsgeschwindigkeit bei Erkrankungen wie Multipler Sklerose zuverl\xe4ssig ab. Was sie nicht sauber zeigt, ist ein breiter Transfer: Das \xdcben macht nicht zuverl\xe4ssig anderes Denken, das Ged\xe4chtnis oder die allgemeine Intelligenz besser, und Fachleute betonen, dass der Test nicht prozessrein ist \u2013 Verbesserung kann ebenso vom Auswendiglernen der Legende kommen wie von schnellerer Verarbeitung. Sieh das Ergebnis als Ma\xdf f\xfcr genau diese Fertigkeit, nicht als Beweis f\xfcr einen insgesamt sch\xe4rferen Verstand.",rec:"Merke dir die Legende in den ersten zehn Sekunden und halte danach ein gleichm\xe4\xdfiges, ununterbrochenes Tempo; wer zum \xdcberpr\xfcfen inneh\xe4lt, verliert mehr Zeit, als die paar Fehler gekostet h\xe4tten.",faq:[["Ist das dasselbe wie ein Ged\xe4chtnistest?","Nicht wirklich. Das Ged\xe4chtnis hilft, sobald du die Legende gelernt hast, aber die Kernanforderung ist die Zuordnungsgeschwindigkeit \u2013 damit liegt die Aufgabe n\xe4her an Aufmerksamkeit und Verarbeitungsgeschwindigkeit als am Ged\xe4chtnis."],["Warum schwankt mein Ergebnis so stark zwischen den Durchg\xe4ngen?","Kurze Geschwindigkeitsaufgaben auf Zeit sind von Natur aus verrauscht, und wie gut du dir die Legende in dem Durchgang gemerkt hast, f\xe4llt stark ins Gewicht. Schau auf deinen Durchschnitt \xfcber mehrere Durchg\xe4nge statt auf ein einzelnes Ergebnis."],["Macht mich das Training im Alltag kl\xfcger?","Es macht dich schneller bei dieser Art von Ersetzung und \xe4hnlichen Geschwindigkeitsaufgaben. Es gibt kaum belastbare Hinweise, dass es die allgemeine Intelligenz oder unverwandte Fertigkeiten hebt \u2013 genie\xdfe also die Sch\xe4rfung hier, ohne einen breiten \xdcbertrag zu erwarten."]],variants:"Es gibt eine m\xfcndliche Version, bei der du die Ziffer nennst statt sie einzutippen \u2013 klinisch genutzt, um die Schreibgeschwindigkeit aus dem Ergebnis herauszunehmen \u2013, und eine schriftliche Version, bei der du die Ziffern von Hand eintr\xe4gst. Der eng verwandte Digit Symbol Substitution Test dreht die Anforderung um, indem du das Symbol zeichnest, und computergest\xfctzte Ausgaben erg\xe4nzen zuf\xe4llig gemischte Legenden und einen mitlaufend steigenden Schwierigkeitsgrad."},pt:{about:"O SDMT apresenta uma legenda que associa nove s\xedmbolos abstratos aos d\xedgitos de 1 a 9. Em seguida surge uma fileira de s\xedmbolos e a sua tarefa \xe9 digitar o d\xedgito correspondente a cada um, o maior n\xfamero poss\xedvel antes de o tempo acabar. \xc9 uma tarefa de pura velocidade: a regra \xe9 trivial, mas voc\xea precisa aplic\xe1-la repetidamente sem perder o ritmo.",benefit:"Treina principalmente a velocidade de processamento, ou seja, o ritmo com que voc\xea capta um est\xedmulo, encontra a resposta certa e a executa. Como voc\xea olha constantemente de volta para a legenda, tamb\xe9m recruta a varredura visual, a aten\xe7\xe3o sustentada e um pouco de mem\xf3ria de curto prazo a partir do momento em que come\xe7a a guardar pares de cor.",history:"O formato s\xedmbolo-d\xedgito surgiu da tarefa de substitui\xe7\xe3o d\xedgito-s\xedmbolo usada em baterias de intelig\xeancia desde o in\xedcio do s\xe9culo XX, incluindo as escalas Wechsler. Aaron Smith reformulou-a nos anos 1960 para que a pessoa dissesse ou escrevesse o d\xedgito em vez de desenhar o s\xedmbolo, o que a tornou mais r\xe1pida e menos dependente da linguagem. Ap\xf3s a sua publica\xe7\xe3o em 1973, o SDMT espalhou-se amplamente pela neuropsicologia e, a partir dos anos 1990, tornou-se uma medida padr\xe3o da velocidade cognitiva na investiga\xe7\xe3o sobre esclerose m\xfaltipla.",creator:"Foi criado pelo neuropsic\xf3logo norte-americano Aaron Smith, que o testou ao longo dos anos 1960 e o publicou formalmente em 1973 atrav\xe9s da Western Psychological Services, em Los Angeles. A ideia de fundo, a substitui\xe7\xe3o, \xe9 mais antiga e n\xe3o \xe9 inven\xe7\xe3o dele, mas esta vers\xe3o espec\xedfica de s\xedmbolo para d\xedgito \xe9 sua.",methods:"Grave a legenda na mem\xf3ria logo no in\xedcio para deixar de precisar de a consultar; os primeiros pares que voc\xea memoriza d\xe3o o maior ganho de velocidade. Mantenha um ritmo constante da esquerda para a direita em vez de acelerar e travar, e resista \xe0 vontade de reconferir respostas que j\xe1 sabe. Se errar um par, reancore-o de prop\xf3sito em vez de adivinhar v\xe1rias vezes.",duration:"As sess\xf5es curtas funcionam melhor: algumas rodadas cronometradas de um a dois minutos, em poucos dias por semana. A tarefa \xe9 mentalmente exigente, por isso a qualidade cai depressa quando voc\xea se cansa; pare quando a sua velocidade estabilizar dentro de uma sess\xe3o, em vez de insistir.",research:"As evid\xeancias s\xe3o mais fortes exatamente para aquilo que seria de esperar: voc\xea fica mais r\xe1pido na pr\xf3pria substitui\xe7\xe3o s\xedmbolo-d\xedgito, e a vers\xe3o cl\xednica acompanha de forma fi\xe1vel as mudan\xe7as na velocidade de processamento em condi\xe7\xf5es como a esclerose m\xfaltipla. O que n\xe3o demonstra com clareza \xe9 a transfer\xeancia ampla: pratic\xe1-la n\xe3o torna de forma fi\xe1vel melhores o racioc\xednio, a mem\xf3ria ou a intelig\xeancia geral n\xe3o relacionados, e os investigadores frisam que o teste n\xe3o \xe9 puro em termos de processo, por isso a melhoria pode vir tanto de memorizar a legenda como de processar mais r\xe1pido. Encare a pontua\xe7\xe3o como medida desta habilidade, n\xe3o como prova de uma mente mais afiada de modo geral.",rec:"Memorize a legenda nos primeiros dez segundos e depois mantenha um ritmo suave e ininterrupto; quem para para conferir perde mais tempo do que os poucos erros teriam custado.",faq:[["Isto \xe9 o mesmo que um teste de mem\xf3ria?","N\xe3o exatamente. A mem\xf3ria ajuda depois de voc\xea aprender a legenda, mas a exig\xeancia central \xe9 a velocidade de correspond\xeancia, por isso fica mais perto da aten\xe7\xe3o e da velocidade de processamento do que da mem\xf3ria."],["Por que a minha pontua\xe7\xe3o varia tanto de uma rodada para outra?","As tarefas curtas e cronometradas de velocidade s\xe3o naturalmente ruidosas, e o qu\xe3o bem voc\xea lembra a legenda naquela rodada conta muito. Olhe para a sua m\xe9dia ao longo de v\xe1rias rodadas, e n\xe3o para uma pontua\xe7\xe3o isolada."],["Treinar isto vai me tornar mais inteligente no dia a dia?","Torna voc\xea mais r\xe1pido neste tipo de substitui\xe7\xe3o e em tarefas de velocidade semelhantes. H\xe1 pouca evid\xeancia s\xf3lida de que eleve a intelig\xeancia geral ou habilidades n\xe3o relacionadas, ent\xe3o aproveite o ganho aqui sem esperar grandes efeitos em outras \xe1reas."]],variants:"Existe uma vers\xe3o oral, em que voc\xea diz o d\xedgito em vez de digitar, usada clinicamente para retirar do resultado a velocidade de escrita \xe0 m\xe3o, e uma vers\xe3o escrita em que voc\xea preenche os d\xedgitos manualmente. O Teste de Substitui\xe7\xe3o de S\xedmbolos por D\xedgitos, intimamente relacionado, inverte a exig\xeancia fazendo voc\xea desenhar o s\xedmbolo, e as edi\xe7\xf5es computorizadas acrescentam legendas aleat\xf3rias e dificuldade crescente."},hi:{about:"SDMT \u0906\u092a\u0915\u094b \u090f\u0915 \u0915\u0941\u0902\u091c\u0940 \u0926\u093f\u0916\u093e\u0924\u093e \u0939\u0948 \u091c\u094b \u0928\u094c \u0905\u092e\u0942\u0930\u094d\u0924 \u091a\u093f\u0939\u094d\u0928\u094b\u0902 \u0915\u094b 1 \u0938\u0947 9 \u0924\u0915 \u0915\u0947 \u0905\u0902\u0915\u094b\u0902 \u0915\u0947 \u0938\u093e\u0925 \u091c\u094b\u0921\u093c\u0924\u0940 \u0939\u0948\u0964 \u092b\u093f\u0930 \u091a\u093f\u0939\u094d\u0928\u094b\u0902 \u0915\u0940 \u090f\u0915 \u092a\u0902\u0915\u094d\u0924\u093f \u0926\u093f\u0916\u093e\u0908 \u0926\u0947\u0924\u0940 \u0939\u0948, \u0914\u0930 \u0906\u092a\u0915\u093e \u0915\u093e\u092e \u0939\u0948 \u0939\u0930 \u091a\u093f\u0939\u094d\u0928 \u0915\u0947 \u0932\u093f\u090f \u0909\u0938\u0938\u0947 \u092e\u0947\u0932 \u0916\u093e\u0924\u093e \u0905\u0902\u0915 \u091f\u093e\u0907\u092a \u0915\u0930\u0928\u093e \u2014 \u091c\u093f\u0924\u0928\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0939\u094b \u0938\u0915\u0947\u0902, \u0938\u092e\u092f \u0916\u0924\u094d\u092e \u0939\u094b\u0928\u0947 \u0938\u0947 \u092a\u0939\u0932\u0947\u0964 \u092f\u0939 \u0935\u093f\u0936\u0941\u0926\u094d\u0927 \u0930\u0942\u092a \u0938\u0947 \u0917\u0924\u093f \u0915\u093e \u0915\u093e\u092e \u0939\u0948: \u0928\u093f\u092f\u092e \u092c\u0947\u0939\u0926 \u0906\u0938\u093e\u0928 \u0939\u0948, \u092a\u0930 \u0906\u092a\u0915\u094b \u0909\u0938\u0947 \u092c\u093e\u0930-\u092c\u093e\u0930 \u092c\u093f\u0928\u093e \u0930\u092b\u093c\u094d\u0924\u093e\u0930 \u0918\u091f\u093e\u090f \u0932\u093e\u0917\u0942 \u0915\u0930\u0924\u0947 \u0930\u0939\u0928\u093e \u0939\u0948\u0964",benefit:"\u092f\u0939 \u092e\u0941\u0916\u094d\u092f \u0930\u0942\u092a \u0938\u0947 \u092a\u094d\u0930\u094b\u0938\u0947\u0938\u093f\u0902\u0917 \u0938\u094d\u092a\u0940\u0921 \u0915\u094b \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u093f\u0924 \u0915\u0930\u0924\u093e \u0939\u0948 \u2014 \u092f\u093e\u0928\u0940 \u0935\u0939 \u0926\u0930 \u091c\u093f\u0938 \u092a\u0930 \u0906\u092a \u0915\u094b\u0908 \u0909\u0926\u094d\u0926\u0940\u092a\u0928 \u0917\u094d\u0930\u0939\u0923 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902, \u0938\u0939\u0940 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0922\u0942\u0901\u0922\u0924\u0947 \u0939\u0948\u0902 \u0914\u0930 \u0909\u0938 \u092a\u0930 \u0905\u092e\u0932 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902\u0964 \u091a\u0942\u0901\u0915\u093f \u0906\u092a \u0932\u0917\u093e\u0924\u093e\u0930 \u092a\u0932\u091f-\u092a\u0932\u091f\u0915\u0930 \u0915\u0941\u0902\u091c\u0940 \u0926\u0947\u0916\u0924\u0947 \u0939\u0948\u0902, \u092f\u0939 \u0926\u0943\u0936\u094d\u092f \u0938\u094d\u0915\u0948\u0928\u093f\u0902\u0917, \u0928\u093f\u0930\u0902\u0924\u0930 \u0927\u094d\u092f\u093e\u0928 \u0914\u0930 \u0925\u094b\u0921\u093c\u0940-\u092c\u0939\u0941\u0924 \u0905\u0932\u094d\u092a\u0915\u093e\u0932\u093f\u0915 \u0938\u094d\u092e\u0943\u0924\u093f \u092a\u0930 \u092d\u0940 \u091f\u093f\u0915\u093e \u0930\u0939\u0924\u093e \u0939\u0948 \u2014 \u0916\u093e\u0938\u0915\u0930 \u091c\u092c \u0906\u092a \u091c\u094b\u0921\u093c\u093f\u092f\u094b\u0902 \u0915\u094b \u0926\u093f\u092e\u093e\u0917 \u092e\u0947\u0902 \u0930\u0916\u0928\u093e \u0936\u0941\u0930\u0942 \u0915\u0930 \u0926\u0947\u0924\u0947 \u0939\u0948\u0902\u0964",history:"\u091a\u093f\u0939\u094d\u0928-\u0905\u0902\u0915 \u0915\u093e \u092f\u0939 \u092a\u094d\u0930\u093e\u0930\u0942\u092a 20\u0935\u0940\u0902 \u0938\u0926\u0940 \u0915\u0947 \u0936\u0941\u0930\u0942 \u0938\u0947 \u092c\u0941\u0926\u094d\u0927\u093f-\u092a\u0930\u0940\u0915\u094d\u0937\u0923 \u092c\u0948\u091f\u0930\u093f\u092f\u094b\u0902 \u092e\u0947\u0902 \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0939\u094b\u0924\u0947 \u0906\u090f \u0905\u0902\u0915-\u091a\u093f\u0939\u094d\u0928 \u092a\u094d\u0930\u0924\u093f\u0938\u094d\u0925\u093e\u092a\u0928 \u0915\u093e\u0930\u094d\u092f \u0938\u0947 \u0928\u093f\u0915\u0932\u093e, \u091c\u093f\u0938\u092e\u0947\u0902 \u0935\u0947\u0915\u094d\u0938\u094d\u0932\u0930 \u0938\u094d\u0915\u0947\u0932 \u092d\u0940 \u0936\u093e\u092e\u093f\u0932 \u0939\u0948\u0902\u0964 Aaron Smith \u0928\u0947 1960 \u0915\u0947 \u0926\u0936\u0915 \u092e\u0947\u0902 \u0907\u0938\u0947 \u092b\u093f\u0930 \u0938\u0947 \u0917\u0922\u093c\u093e \u0924\u093e\u0915\u093f \u0935\u094d\u092f\u0915\u094d\u0924\u093f \u091a\u093f\u0939\u094d\u0928 \u092c\u0928\u093e\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u0905\u0902\u0915 \u092c\u094b\u0932\u0947 \u092f\u093e \u0932\u093f\u0916\u0947 \u2014 \u0907\u0938\u0938\u0947 \u092f\u0939 \u0924\u0947\u091c\u093c \u0914\u0930 \u092d\u093e\u0937\u093e \u092a\u0930 \u0915\u092e \u0928\u093f\u0930\u094d\u092d\u0930 \u0939\u094b \u0917\u092f\u093e\u0964 1973 \u092e\u0947\u0902 \u092a\u094d\u0930\u0915\u093e\u0936\u0928 \u0915\u0947 \u092c\u093e\u0926 SDMT \u0928\u094d\u092f\u0942\u0930\u094b\u0938\u093e\u0907\u0915\u094b\u0932\u0949\u091c\u0940 \u092e\u0947\u0902 \u0935\u094d\u092f\u093e\u092a\u0915 \u0930\u0942\u092a \u0938\u0947 \u092b\u0948\u0932\u093e \u0914\u0930 1990 \u0915\u0947 \u0926\u0936\u0915 \u0938\u0947 \u092e\u0932\u094d\u091f\u093f\u092a\u0932 \u0938\u094d\u0915\u094d\u0932\u0947\u0930\u094b\u0938\u093f\u0938 \u0905\u0928\u0941\u0938\u0902\u0927\u093e\u0928 \u092e\u0947\u0902 \u0938\u0902\u091c\u094d\u091e\u093e\u0928\u093e\u0924\u094d\u092e\u0915 \u0917\u0924\u093f \u0915\u093e \u090f\u0915 \u092e\u093e\u0928\u0915 \u092e\u093e\u092a \u092c\u0928 \u0917\u092f\u093e\u0964",creator:"\u0907\u0938\u0947 \u0905\u092e\u0947\u0930\u093f\u0915\u0940 \u0928\u094d\u092f\u0942\u0930\u094b\u0938\u093e\u0907\u0915\u094b\u0932\u0949\u091c\u093f\u0938\u094d\u091f Aaron Smith \u0928\u0947 \u092c\u0928\u093e\u092f\u093e, \u091c\u093f\u0928\u094d\u0939\u094b\u0902\u0928\u0947 1960 \u0915\u0947 \u0926\u0936\u0915 \u092d\u0930 \u0907\u0938\u0915\u093e \u092a\u0930\u0940\u0915\u094d\u0937\u0923 \u0915\u093f\u092f\u093e \u0914\u0930 1973 \u092e\u0947\u0902 \u0932\u0949\u0938 \u090f\u0902\u091c\u0947\u0932\u093f\u0938 \u0915\u0940 Western Psychological Services \u0915\u0947 \u091c\u093c\u0930\u093f\u090f \u0907\u0938\u0947 \u0914\u092a\u091a\u093e\u0930\u093f\u0915 \u0930\u0942\u092a \u0938\u0947 \u092a\u094d\u0930\u0915\u093e\u0936\u093f\u0924 \u0915\u093f\u092f\u093e\u0964 \u092a\u094d\u0930\u0924\u093f\u0938\u094d\u0925\u093e\u092a\u0928 \u0915\u093e \u092e\u0942\u0932 \u0935\u093f\u091a\u093e\u0930 \u0907\u0938\u0938\u0947 \u092a\u0941\u0930\u093e\u0928\u093e \u0939\u0948 \u0914\u0930 \u0909\u0928\u0915\u093e \u0906\u0935\u093f\u0937\u094d\u0915\u093e\u0930 \u0928\u0939\u0940\u0902, \u092a\u0930 \u091a\u093f\u0939\u094d\u0928-\u0938\u0947-\u0905\u0902\u0915 \u0935\u093e\u0932\u093e \u092f\u0939 \u0916\u093e\u0938 \u0930\u0942\u092a \u0909\u0928\u094d\u0939\u0940\u0902 \u0915\u093e \u0939\u0948\u0964",methods:"\u0915\u0941\u0902\u091c\u0940 \u0915\u094b \u0936\u0941\u0930\u0942 \u092e\u0947\u0902 \u0939\u0940 \u0926\u093f\u092e\u093e\u0917 \u092e\u0947\u0902 \u092c\u0948\u0920\u093e \u0932\u0947\u0902 \u0924\u093e\u0915\u093f \u0906\u092a\u0915\u094b \u092c\u093e\u0930-\u092c\u093e\u0930 \u092a\u0940\u091b\u0947 \u0928 \u0926\u0947\u0916\u0928\u093e \u092a\u0921\u093c\u0947; \u092a\u0939\u0932\u0940 \u0915\u0941\u091b \u091c\u094b\u0921\u093c\u093f\u092f\u093e\u0901 \u091c\u094b \u0906\u092a \u092f\u093e\u0926 \u0915\u0930 \u0932\u0947\u0924\u0947 \u0939\u0948\u0902, \u0935\u0947 \u0939\u0940 \u0938\u092c\u0938\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0917\u0924\u093f \u092c\u0922\u093c\u093e\u0924\u0940 \u0939\u0948\u0902\u0964 \u0926\u094c\u0921\u093c\u0928\u0947 \u0914\u0930 \u0905\u091f\u0915\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u092c\u093e\u090f\u0901-\u0938\u0947-\u0926\u093e\u090f\u0901 \u090f\u0915 \u0938\u094d\u0925\u093f\u0930 \u0932\u092f \u092c\u0928\u093e\u090f \u0930\u0916\u0947\u0902, \u0914\u0930 \u091c\u094b \u091c\u0935\u093e\u092c \u0906\u092a \u092a\u0939\u0932\u0947 \u0938\u0947 \u091c\u093e\u0928\u0924\u0947 \u0939\u0948\u0902 \u0909\u0928\u094d\u0939\u0947\u0902 \u0926\u094b\u092c\u093e\u0930\u093e \u091c\u093e\u0901\u091a\u0928\u0947 \u0915\u0947 \u0932\u093e\u0932\u091a \u0938\u0947 \u092c\u091a\u0947\u0902\u0964 \u0905\u0917\u0930 \u0915\u094b\u0908 \u091c\u094b\u0921\u093c\u0940 \u0917\u0932\u0924 \u092f\u093e\u0926 \u0930\u0939 \u0917\u0908 \u0939\u094b, \u0924\u094b \u092c\u093e\u0930-\u092c\u093e\u0930 \u0905\u0902\u0926\u093e\u091c\u093c\u093e \u0932\u0917\u093e\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u0909\u0938\u0947 \u091c\u093e\u0928-\u092c\u0942\u091d\u0915\u0930 \u092b\u093f\u0930 \u0938\u0947 \u0920\u0940\u0915 \u0938\u0947 \u092c\u0948\u0920\u093e \u0932\u0947\u0902\u0964",duration:"\u091b\u094b\u091f\u0947-\u091b\u094b\u091f\u0947 \u0926\u094c\u0930 \u0938\u092c\u0938\u0947 \u0905\u091a\u094d\u091b\u0947 \u0930\u0939\u0924\u0947 \u0939\u0948\u0902: \u090f\u0915 \u0938\u0947 \u0926\u094b \u092e\u093f\u0928\u091f \u0915\u0947 \u0915\u0941\u091b \u0938\u092e\u092f\u092c\u0926\u094d\u0927 \u0930\u093e\u0909\u0902\u0921, \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u0915\u0941\u091b\u0947\u0915 \u0926\u093f\u0928\u0964 \u092f\u0939 \u0915\u093e\u092e \u0926\u093f\u092e\u093e\u0917\u0940 \u0924\u094c\u0930 \u092a\u0930 \u0925\u0915\u093e\u0928\u0947 \u0935\u093e\u0932\u093e \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0925\u0915\u0924\u0947 \u0939\u0940 \u0917\u0941\u0923\u0935\u0924\u094d\u0924\u093e \u0924\u0947\u091c\u093c\u0940 \u0938\u0947 \u0917\u093f\u0930\u0924\u0940 \u0939\u0948; \u090f\u0915 \u0939\u0940 \u0938\u0924\u094d\u0930 \u092e\u0947\u0902 \u091c\u092c \u0906\u092a\u0915\u0940 \u0917\u0924\u093f \u090f\u0915 \u091c\u0917\u0939 \u0920\u0939\u0930 \u091c\u093e\u090f, \u0924\u094b \u0930\u091f \u0932\u0917\u093e\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u0930\u0941\u0915 \u091c\u093e\u090f\u0901\u0964",research:"\u0938\u092c\u0942\u0924 \u0920\u0940\u0915 \u0909\u0938\u0940 \u092c\u093e\u0924 \u0915\u0947 \u0932\u093f\u090f \u0938\u092c\u0938\u0947 \u092e\u091c\u093c\u092c\u0942\u0924 \u0939\u0948\u0902 \u091c\u093f\u0938\u0915\u0940 \u0906\u092a \u0909\u092e\u094d\u092e\u0940\u0926 \u0915\u0930\u0947\u0902\u0917\u0947 \u2014 \u092f\u093e\u0928\u0940 \u0906\u092a \u091a\u093f\u0939\u094d\u0928-\u0905\u0902\u0915 \u092a\u094d\u0930\u0924\u093f\u0938\u094d\u0925\u093e\u092a\u0928 \u092e\u0947\u0902 \u0916\u0941\u0926 \u0939\u0940 \u0924\u0947\u091c\u093c \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u0907\u0938\u0915\u093e \u0915\u094d\u0932\u093f\u0928\u093f\u0915\u0932 \u0930\u0942\u092a \u092e\u0932\u094d\u091f\u093f\u092a\u0932 \u0938\u094d\u0915\u094d\u0932\u0947\u0930\u094b\u0938\u093f\u0938 \u091c\u0948\u0938\u0940 \u0938\u094d\u0925\u093f\u0924\u093f\u092f\u094b\u0902 \u092e\u0947\u0902 \u092a\u094d\u0930\u094b\u0938\u0947\u0938\u093f\u0902\u0917-\u0938\u094d\u092a\u0940\u0921 \u0915\u0947 \u092c\u0926\u0932\u093e\u0935\u094b\u0902 \u0915\u094b \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0922\u0902\u0917 \u0938\u0947 \u0928\u093e\u092a\u0924\u093e \u0939\u0948\u0964 \u091c\u094b \u092c\u093e\u0924 \u0938\u093e\u092b\u093c \u0924\u094c\u0930 \u092a\u0930 \u0938\u093e\u092e\u0928\u0947 \u0928\u0939\u0940\u0902 \u0906\u0924\u0940 \u0935\u0939 \u0939\u0948 \u0935\u094d\u092f\u093e\u092a\u0915 \u0938\u094d\u0925\u093e\u0928\u093e\u0902\u0924\u0930\u0923: \u0907\u0938\u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0930\u0928\u0947 \u0938\u0947 \u0905\u0938\u0902\u092c\u0902\u0927\u093f\u0924 \u0938\u094b\u091a, \u0938\u094d\u092e\u0943\u0924\u093f \u092f\u093e \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u092c\u0941\u0926\u094d\u0927\u093f \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0930\u0942\u092a \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u0928\u0939\u0940\u0902 \u0939\u094b\u0924\u0940, \u0914\u0930 \u0936\u094b\u0927\u0915\u0930\u094d\u0924\u093e \u091c\u093c\u094b\u0930 \u0926\u0947\u0924\u0947 \u0939\u0948\u0902 \u0915\u093f \u092f\u0939 \u092a\u0930\u0940\u0915\u094d\u0937\u0923 \u092a\u094d\u0930\u0915\u094d\u0930\u093f\u092f\u093e-\u0936\u0941\u0926\u094d\u0927 \u0928\u0939\u0940\u0902 \u0939\u0948 \u2014 \u0907\u0938\u0932\u093f\u090f \u0938\u0941\u0927\u093e\u0930 \u091c\u093f\u0924\u0928\u093e \u0924\u0947\u091c\u093c \u092a\u094d\u0930\u094b\u0938\u0947\u0938\u093f\u0902\u0917 \u0938\u0947 \u0906 \u0938\u0915\u0924\u093e \u0939\u0948 \u0909\u0924\u0928\u093e \u0939\u0940 \u0915\u0941\u0902\u091c\u0940 \u0930\u091f \u0932\u0947\u0928\u0947 \u0938\u0947 \u092d\u0940\u0964 \u0905\u0902\u0915 \u0915\u094b \u0907\u0938\u0940 \u0915\u094c\u0936\u0932 \u0915\u093e \u092e\u093e\u092a \u092e\u093e\u0928\u0947\u0902, \u0938\u092e\u0917\u094d\u0930 \u0930\u0942\u092a \u0938\u0947 \u0924\u0947\u091c\u093c \u0926\u093f\u092e\u093e\u0917 \u0915\u093e \u092a\u094d\u0930\u092e\u093e\u0923 \u0928\u0939\u0940\u0902\u0964",rec:"\u092a\u0939\u0932\u0947 \u0926\u0938 \u0938\u0947\u0915\u0902\u0921 \u092e\u0947\u0902 \u0939\u0940 \u0915\u0941\u0902\u091c\u0940 \u092f\u093e\u0926 \u0915\u0930 \u0932\u0947\u0902, \u092b\u093f\u0930 \u090f\u0915 \u091a\u093f\u0915\u0928\u0940, \u092c\u093f\u0928\u093e \u0930\u0941\u0915\u093e\u0935\u091f \u0935\u093e\u0932\u0940 \u0930\u092b\u093c\u094d\u0924\u093e\u0930 \u092c\u0928\u093e\u090f \u0930\u0916\u0947\u0902; \u091c\u094b \u0932\u094b\u0917 \u091c\u093e\u0901\u091a\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0930\u0941\u0915\u0924\u0947 \u0939\u0948\u0902 \u0935\u0947 \u0909\u0924\u0928\u0947 \u0938\u092e\u092f \u0938\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0917\u0901\u0935\u093e \u0926\u0947\u0924\u0947 \u0939\u0948\u0902 \u091c\u093f\u0924\u0928\u093e \u0915\u0941\u091b \u0917\u0932\u0924\u093f\u092f\u094b\u0902 \u092a\u0930 \u092a\u0921\u093c\u0924\u093e\u0964",faq:[["\u0915\u094d\u092f\u093e \u092f\u0939 \u0938\u094d\u092e\u0943\u0924\u093f \u092a\u0930\u0940\u0915\u094d\u0937\u0923 \u091c\u0948\u0938\u093e \u0939\u0940 \u0939\u0948?","\u0920\u0940\u0915 \u0935\u0948\u0938\u093e \u0928\u0939\u0940\u0902\u0964 \u090f\u0915 \u092c\u093e\u0930 \u0915\u0941\u0902\u091c\u0940 \u0938\u0940\u0916 \u0932\u0947\u0928\u0947 \u0915\u0947 \u092c\u093e\u0926 \u0938\u094d\u092e\u0943\u0924\u093f \u092e\u0926\u0926 \u0915\u0930\u0924\u0940 \u0939\u0948, \u092a\u0930 \u092e\u0941\u0916\u094d\u092f \u092e\u093e\u0901\u0917 \u092e\u093f\u0932\u093e\u0928 \u0915\u0940 \u0917\u0924\u093f \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u092f\u0939 \u0938\u094d\u092e\u0943\u0924\u093f \u0938\u0947 \u0915\u0939\u0940\u0902 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0927\u094d\u092f\u093e\u0928 \u0914\u0930 \u092a\u094d\u0930\u094b\u0938\u0947\u0938\u093f\u0902\u0917 \u0938\u094d\u092a\u0940\u0921 \u0915\u0947 \u0915\u0930\u0940\u092c \u092c\u0948\u0920\u0924\u093e \u0939\u0948\u0964"],["\u092e\u0947\u0930\u093e \u0938\u094d\u0915\u094b\u0930 \u0930\u093e\u0909\u0902\u0921-\u0926\u0930-\u0930\u093e\u0909\u0902\u0921 \u0907\u0924\u0928\u093e \u090a\u092a\u0930-\u0928\u0940\u091a\u0947 \u0915\u094d\u092f\u094b\u0902 \u0939\u094b\u0924\u093e \u0930\u0939\u0924\u093e \u0939\u0948?","\u091b\u094b\u091f\u0947 \u0938\u092e\u092f\u092c\u0926\u094d\u0927 \u0917\u0924\u093f-\u0915\u093e\u0930\u094d\u092f \u0938\u094d\u0935\u092d\u093e\u0935 \u0938\u0947 \u0939\u0940 \u0905\u0938\u094d\u0925\u093f\u0930 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u0909\u0938 \u0926\u094c\u0930 \u092e\u0947\u0902 \u0906\u092a\u0928\u0947 \u0915\u0941\u0902\u091c\u0940 \u0915\u093f\u0924\u0928\u0940 \u0905\u091a\u094d\u091b\u0940 \u0924\u0930\u0939 \u092f\u093e\u0926 \u0930\u0916\u0940, \u092f\u0939 \u092c\u0939\u0941\u0924 \u092e\u093e\u092f\u0928\u0947 \u0930\u0916\u0924\u093e \u0939\u0948\u0964 \u0915\u093f\u0938\u0940 \u090f\u0915 \u0938\u094d\u0915\u094b\u0930 \u0915\u0947 \u092c\u091c\u093e\u092f \u0915\u0908 \u0930\u093e\u0909\u0902\u0921 \u0915\u0947 \u0905\u092a\u0928\u0947 \u0914\u0938\u0924 \u0915\u094b \u0926\u0947\u0916\u0947\u0902\u0964"],["\u0915\u094d\u092f\u093e \u0907\u0938\u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0930\u0928\u0947 \u0938\u0947 \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0940 \u091c\u093c\u093f\u0902\u0926\u0917\u0940 \u092e\u0947\u0902 \u092e\u0948\u0902 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0939\u094b\u0936\u093f\u092f\u093e\u0930 \u0939\u094b \u091c\u093e\u090a\u0901\u0917\u093e?","\u092f\u0939 \u0906\u092a\u0915\u094b \u0907\u0938 \u0924\u0930\u0939 \u0915\u0947 \u092a\u094d\u0930\u0924\u093f\u0938\u094d\u0925\u093e\u092a\u0928 \u0914\u0930 \u092e\u093f\u0932\u0924\u0947-\u091c\u0941\u0932\u0924\u0947 \u0917\u0924\u093f-\u0915\u093e\u0930\u094d\u092f\u094b\u0902 \u092e\u0947\u0902 \u0924\u0947\u091c\u093c \u092c\u0928\u093e\u0924\u093e \u0939\u0948\u0964 \u0907\u0938 \u092c\u093e\u0924 \u0915\u0947 \u092c\u0939\u0941\u0924 \u0915\u092e \u092a\u0941\u0916\u093c\u094d\u0924\u093e \u0938\u092c\u0942\u0924 \u0939\u0948\u0902 \u0915\u093f \u0907\u0938\u0938\u0947 \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u092c\u0941\u0926\u094d\u0927\u093f \u092f\u093e \u0905\u0938\u0902\u092c\u0902\u0927\u093f\u0924 \u0915\u094c\u0936\u0932 \u092c\u0922\u093c\u0924\u0947 \u0939\u0948\u0902, \u0907\u0938\u0932\u093f\u090f \u092f\u0939\u093e\u0901 \u0939\u094b\u0924\u0940 \u0927\u093e\u0930 \u0915\u093e \u0906\u0928\u0902\u0926 \u0932\u0947\u0902, \u092a\u0930 \u0935\u094d\u092f\u093e\u092a\u0915 \u092b\u0948\u0932\u093e\u0935 \u0915\u0940 \u0909\u092e\u094d\u092e\u0940\u0926 \u0928 \u0930\u0916\u0947\u0902\u0964"]],variants:"\u090f\u0915 \u092e\u094c\u0916\u093f\u0915 \u0930\u0942\u092a \u0939\u0948, \u091c\u093f\u0938\u092e\u0947\u0902 \u0906\u092a \u091f\u093e\u0907\u092a \u0915\u0930\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u0905\u0902\u0915 \u092c\u094b\u0932\u0924\u0947 \u0939\u0948\u0902 \u2014 \u0907\u0938\u0947 \u0915\u094d\u0932\u093f\u0928\u093f\u0915\u0932 \u0924\u094c\u0930 \u092a\u0930 \u0907\u0938\u0932\u093f\u090f \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0915\u093f\u092f\u093e \u091c\u093e\u0924\u093e \u0939\u0948 \u0924\u093e\u0915\u093f \u0932\u093f\u0916\u093e\u0935\u091f \u0915\u0940 \u0917\u0924\u093f \u0915\u093e \u0905\u0938\u0930 \u0928\u0924\u0940\u091c\u0947 \u0938\u0947 \u0939\u091f \u091c\u093e\u090f \u2014 \u0914\u0930 \u090f\u0915 \u0932\u093f\u0916\u093f\u0924 \u0930\u0942\u092a \u0939\u0948 \u091c\u093f\u0938\u092e\u0947\u0902 \u0906\u092a \u0939\u093e\u0925 \u0938\u0947 \u0905\u0902\u0915 \u092d\u0930\u0924\u0947 \u0939\u0948\u0902\u0964 \u0907\u0938\u0938\u0947 \u092c\u0939\u0941\u0924 \u092e\u093f\u0932\u0924\u093e-\u091c\u0941\u0932\u0924\u093e Digit Symbol Substitution Test \u092e\u093e\u0901\u0917 \u0915\u094b \u0909\u0932\u091f \u0926\u0947\u0924\u093e \u0939\u0948, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u0909\u0938\u092e\u0947\u0902 \u0906\u092a\u0915\u094b \u091a\u093f\u0939\u094d\u0928 \u092c\u0928\u093e\u0928\u093e \u092a\u0921\u093c\u0924\u093e \u0939\u0948, \u0914\u0930 \u0915\u092e\u094d\u092a\u094d\u092f\u0942\u091f\u0930\u0940\u0915\u0943\u0924 \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0915\u094d\u0930\u092e\u0930\u0939\u093f\u0924 \u0915\u0941\u0902\u091c\u093f\u092f\u093e\u0901 \u0914\u0930 \u092c\u0922\u093c\u0924\u0940 \u0915\u0920\u093f\u0928\u093e\u0908 \u091c\u094b\u0921\u093c \u0926\u0947\u0924\u0947 \u0939\u0948\u0902\u0964"},zh:{about:"SDMT \u4f1a\u5148\u7ed9\u4f60\u4e00\u5f20\u5bf9\u7167\u8868\uff0c\u628a\u4e5d\u4e2a\u62bd\u8c61\u7b26\u53f7\u5206\u522b\u548c\u6570\u5b57 1 \u5230 9 \u914d\u6210\u4e00\u5bf9\u3002\u63a5\u7740\u5c4f\u5e55\u4e0a\u51fa\u73b0\u4e00\u6392\u7b26\u53f7\uff0c\u4f60\u7684\u4efb\u52a1\u5c31\u662f\u4e3a\u6bcf\u4e2a\u7b26\u53f7\u6572\u51fa\u5bf9\u5e94\u7684\u6570\u5b57\uff0c\u5728\u8ba1\u65f6\u7ed3\u675f\u524d\u5c3d\u91cf\u591a\u7b54\u3002\u8fd9\u662f\u4e00\u9879\u7eaf\u7cb9\u6bd4\u62fc\u901f\u5ea6\u7684\u4efb\u52a1\uff1a\u89c4\u5219\u6781\u5176\u7b80\u5355\uff0c\u96be\u7684\u662f\u8981\u4e00\u904d\u53c8\u4e00\u904d\u5730\u5957\u7528\u5b83\u800c\u4e0d\u653e\u6162\u8282\u594f\u3002",benefit:"\u5b83\u4e3b\u8981\u953b\u70bc\u7684\u662f\u52a0\u5de5\u901f\u5ea6\uff0c\u4e5f\u5c31\u662f\u4f60\u63a5\u6536\u4e00\u4e2a\u523a\u6fc0\u3001\u67e5\u627e\u6b63\u786e\u53cd\u5e94\u518d\u505a\u51fa\u53cd\u5e94\u7684\u5feb\u6162\u3002\u7531\u4e8e\u4f60\u8981\u4e0d\u65ad\u56de\u770b\u5bf9\u7167\u8868\uff0c\u5b83\u8fd8\u4f1a\u7528\u5230\u89c6\u89c9\u626b\u63cf\u3001\u6301\u7eed\u6027\u6ce8\u610f\uff0c\u4ee5\u53ca\u5f53\u4f60\u5f00\u59cb\u628a\u7b26\u53f7\u5bf9\u8bb0\u5728\u8111\u5b50\u91cc\u65f6\u7684\u4e00\u70b9\u77ed\u65f6\u8bb0\u5fc6\u3002",history:"\u7b26\u53f7-\u6570\u5b57\u8fd9\u79cd\u5f62\u5f0f\uff0c\u6e90\u81ea\u4e8c\u5341\u4e16\u7eaa\u521d\u5c31\u7528\u4e8e\u667a\u529b\u6d4b\u9a8c\u7ec4\u5408\uff08\u5305\u62ec\u97e6\u6c0f\u91cf\u8868\uff09\u7684\u6570\u5b57-\u7b26\u53f7\u66ff\u6362\u4efb\u52a1\u3002Aaron Smith \u5728 1960 \u5e74\u4ee3\u5bf9\u5b83\u505a\u4e86\u6539\u9020\uff0c\u8ba9\u53d7\u8bd5\u8005\u8bf4\u51fa\u6216\u5199\u51fa\u6570\u5b57\uff0c\u800c\u4e0d\u662f\u53bb\u753b\u7b26\u53f7\uff0c\u8fd9\u6837\u65e2\u66f4\u5feb\uff0c\u4e5f\u51e0\u4e4e\u4e0d\u4f9d\u8d56\u8bed\u8a00\u30021973 \u5e74\u6b63\u5f0f\u53d1\u8868\u540e\uff0cSDMT \u5728\u795e\u7ecf\u5fc3\u7406\u5b66\u9886\u57df\u5e7f\u6cdb\u4f20\u64ad\uff0c\u5e76\u4ece 1990 \u5e74\u4ee3\u8d77\u6210\u4e3a\u591a\u53d1\u6027\u786c\u5316\u7814\u7a76\u4e2d\u8861\u91cf\u8ba4\u77e5\u901f\u5ea6\u7684\u6807\u51c6\u5de5\u5177\u3002",creator:"\u5b83\u7531\u7f8e\u56fd\u795e\u7ecf\u5fc3\u7406\u5b66\u5bb6 Aaron Smith \u521b\u5236\uff0c\u4ed6\u5728\u6574\u4e2a 1960 \u5e74\u4ee3\u4e0d\u65ad\u8bd5\u7528\uff0c\u5e76\u4e8e 1973 \u5e74\u901a\u8fc7\u6d1b\u6749\u77f6\u7684 Western Psychological Services \u6b63\u5f0f\u53d1\u8868\u3002\u80cc\u540e\u7684\u66ff\u6362\u601d\u8def\u66f4\u4e3a\u53e4\u8001\uff0c\u5e76\u975e\u4ed6\u7684\u53d1\u660e\uff0c\u4f46\u8fd9\u5957\u7279\u5b9a\u7684\u300c\u7b26\u53f7\u5bf9\u5e94\u6570\u5b57\u300d\u7248\u672c\u51fa\u81ea\u4ed6\u624b\u3002",methods:"\u5c3d\u65e9\u628a\u5bf9\u7167\u8868\u7262\u8bb0\u4e8e\u5fc3\uff0c\u8fd9\u6837\u5c31\u80fd\u4e0d\u518d\u56de\u770b\uff1b\u6700\u5148\u8bb0\u4f4f\u7684\u90a3\u51e0\u5bf9\u5e26\u6765\u7684\u63d0\u901f\u6536\u76ca\u6700\u5927\u3002\u4fdd\u6301\u4ece\u5de6\u5230\u53f3\u7684\u7a33\u5b9a\u8282\u594f\uff0c\u522b\u4e00\u4f1a\u513f\u72c2\u8d76\u3001\u4e00\u4f1a\u513f\u5361\u58f3\uff0c\u4e5f\u8981\u5fcd\u4f4f\u53bb\u590d\u6838\u90a3\u4e9b\u4f60\u5df2\u7ecf\u786e\u5b9a\u7684\u7b54\u6848\u3002\u5982\u679c\u67d0\u4e00\u5bf9\u8bb0\u9519\u4e86\uff0c\u5c31\u523b\u610f\u91cd\u65b0\u628a\u5b83\u951a\u5b9a\u4e0b\u6765\uff0c\u800c\u4e0d\u662f\u53cd\u590d\u778e\u731c\u3002",duration:"\u77ed\u65f6\u6bb5\u7ec3\u4e60\u6548\u679c\u6700\u597d\uff1a\u6bcf\u5468\u7ec3\u51e0\u5929\uff0c\u6bcf\u6b21\u505a\u51e0\u8f6e\u4e00\u5230\u4e24\u5206\u949f\u7684\u8ba1\u65f6\u6d4b\u9a8c\u3002\u8fd9\u9879\u4efb\u52a1\u5f88\u8d39\u8111\uff0c\u4e00\u65e6\u75b2\u52b3\uff0c\u8d28\u91cf\u4f1a\u8fc5\u901f\u4e0b\u6ed1\uff1b\u5f53\u5355\u6b21\u7ec3\u4e60\u91cc\u901f\u5ea6\u8fdb\u5165\u5e73\u53f0\u671f\u65f6\u5c31\u8be5\u505c\uff0c\u800c\u4e0d\u662f\u786c\u6491\u3002",research:"\u8bc1\u636e\u6700\u624e\u5b9e\u7684\u6070\u6070\u662f\u4f60\u80fd\u60f3\u5230\u7684\u90a3\u90e8\u5206\uff1a\u4f60\u4f1a\u5728\u7b26\u53f7-\u6570\u5b57\u66ff\u6362\u8fd9\u4ef6\u4e8b\u672c\u8eab\u4e0a\u53d8\u5feb\uff0c\u800c\u4e34\u5e8a\u7248\u672c\u80fd\u53ef\u9760\u5730\u8ffd\u8e2a\u591a\u53d1\u6027\u786c\u5316\u7b49\u75c5\u75c7\u4e2d\u52a0\u5de5\u901f\u5ea6\u7684\u53d8\u5316\u3002\u5b83\u65e0\u6cd5\u5e72\u51c0\u5730\u8bc1\u660e\u7684\u662f\u5e7f\u6cdb\u8fc1\u79fb\uff1a\u7ec3\u5b83\u5e76\u4e0d\u80fd\u53ef\u9760\u5730\u8ba9\u65e0\u5173\u7684\u601d\u7ef4\u3001\u8bb0\u5fc6\u6216\u4e00\u822c\u667a\u529b\u53d8\u597d\uff1b\u7814\u7a76\u8005\u4e5f\u5f3a\u8c03\u8fd9\u4e2a\u6d4b\u9a8c\u5e76\u975e\u300c\u8fc7\u7a0b\u7eaf\u51c0\u300d\uff0c\u6240\u4ee5\u6210\u7ee9\u63d0\u5347\u65e2\u53ef\u80fd\u6765\u81ea\u52a0\u5de5\u53d8\u5feb\uff0c\u4e5f\u53ef\u80fd\u53ea\u662f\u6765\u81ea\u8bb0\u4f4f\u4e86\u5bf9\u7167\u8868\u3002\u628a\u5206\u6570\u5f53\u4f5c\u8861\u91cf\u8fd9\u9879\u5177\u4f53\u6280\u80fd\u7684\u6307\u6807\uff0c\u800c\u4e0d\u662f\u5934\u8111\u6574\u4f53\u66f4\u654f\u9510\u7684\u8bc1\u660e\u3002",rec:"\u5728\u5934\u5341\u79d2\u5185\u628a\u5bf9\u7167\u8868\u8bb0\u4e0b\u6765\uff0c\u7136\u540e\u4fdd\u6301\u6d41\u7545\u4e0d\u4e2d\u65ad\u7684\u8282\u594f\uff1b\u90a3\u4e9b\u505c\u4e0b\u6765\u6838\u5bf9\u7684\u4eba,\u635f\u5931\u7684\u65f6\u95f4\u8fdc\u591a\u4e8e\u90a3\u51e0\u4e2a\u9519\u8bef\u672c\u4f1a\u5e26\u6765\u7684\u4ee3\u4ef7\u3002",faq:[["\u8fd9\u548c\u8bb0\u5fc6\u6d4b\u9a8c\u662f\u4e00\u56de\u4e8b\u5417\uff1f","\u5176\u5b9e\u4e0d\u662f\u3002\u5b66\u4f1a\u5bf9\u7167\u8868\u4e4b\u540e\u8bb0\u5fc6\u786e\u5b9e\u6709\u5e2e\u52a9\uff0c\u4f46\u6838\u5fc3\u8003\u9a8c\u662f\u914d\u5bf9\u7684\u901f\u5ea6\uff0c\u6240\u4ee5\u5b83\u66f4\u63a5\u8fd1\u6ce8\u610f\u529b\u548c\u52a0\u5de5\u901f\u5ea6\uff0c\u800c\u4e0d\u662f\u8bb0\u5fc6\u3002"],["\u4e3a\u4ec0\u4e48\u6211\u7684\u6210\u7ee9\u5728\u5404\u8f6e\u4e4b\u95f4\u8df3\u52a8\u8fd9\u4e48\u5927\uff1f","\u77ed\u65f6\u8ba1\u65f6\u7684\u901f\u5ea6\u4efb\u52a1\u5929\u751f\u5c31\u5f88\u300c\u5435\u300d\uff0c\u800c\u4f60\u90a3\u4e00\u8f6e\u628a\u5bf9\u7167\u8868\u8bb0\u5f97\u591a\u7262\u5f71\u54cd\u5f88\u5927\u3002\u770b\u51e0\u8f6e\u7684\u5e73\u5747\u503c\uff0c\u800c\u4e0d\u662f\u76ef\u7740\u4efb\u4f55\u5355\u6b21\u6210\u7ee9\u3002"],["\u7ec3\u8fd9\u4e2a\u4f1a\u8ba9\u6211\u5728\u65e5\u5e38\u751f\u6d3b\u4e2d\u66f4\u806a\u660e\u5417\uff1f","\u5b83\u4f1a\u8ba9\u4f60\u5728\u8fd9\u7c7b\u66ff\u6362\u4ee5\u53ca\u7c7b\u4f3c\u7684\u9650\u65f6\u4efb\u52a1\u4e0a\u66f4\u5feb\u3002\u51e0\u4e4e\u6ca1\u6709\u624e\u5b9e\u8bc1\u636e\u8868\u660e\u5b83\u80fd\u63d0\u5347\u4e00\u822c\u667a\u529b\u6216\u65e0\u5173\u6280\u80fd\uff0c\u6240\u4ee5\u5c3d\u7ba1\u4eab\u53d7\u8fd9\u91cc\u7684\u8fdb\u6b65\uff0c\u522b\u6307\u671b\u5b83\u4f1a\u5927\u9762\u79ef\u5916\u6ea2\u3002"]],variants:"\u6709\u53e3\u5934\u7248\uff0c\u4f60\u8bf4\u51fa\u6570\u5b57\u800c\u975e\u6572\u952e\uff0c\u4e34\u5e8a\u4e0a\u7528\u5b83\u6765\u5254\u9664\u624b\u5199\u901f\u5ea6\u5bf9\u7ed3\u679c\u7684\u5f71\u54cd\uff1b\u4e5f\u6709\u4e66\u5199\u7248\uff0c\u7528\u624b\u628a\u6570\u5b57\u586b\u8fdb\u53bb\u3002\u4e0e\u4e4b\u5bc6\u5207\u76f8\u5173\u7684\u6570\u5b57\u7b26\u53f7\u66ff\u6362\u6d4b\u9a8c\uff08Digit Symbol Substitution Test\uff09\u5219\u53cd\u8fc7\u6765\u8981\u6c42\u4f60\u753b\u51fa\u7b26\u53f7\uff0c\u800c\u8ba1\u7b97\u673a\u5316\u7684\u7248\u672c\u4f1a\u52a0\u5165\u968f\u673a\u5bf9\u7167\u8868\u548c\u52a8\u6001\u53d8\u5316\u7684\u96be\u5ea6\u3002"}},"set-game":{ru:{about:"SET: \u0422\u0440\u043e\u0439\u043a\u0438 \u2014 \u0432\u0438\u0437\u0443\u0430\u043b\u044c\u043d\u0430\u044f \u0438\u0433\u0440\u0430 \u043d\u0430 \u043f\u043e\u0438\u0441\u043a \u0437\u0430\u043a\u043e\u043d\u043e\u043c\u0435\u0440\u043d\u043e\u0441\u0442\u0435\u0439. \u0412 \u043a\u043e\u043b\u043e\u0434\u0435 \u043a\u0430\u0436\u0434\u0430\u044f \u043a\u0430\u0440\u0442\u0430 \u0440\u0430\u0437\u043b\u0438\u0447\u0430\u0435\u0442\u0441\u044f \u043f\u043e \u0447\u0435\u0442\u044b\u0440\u0451\u043c \u043f\u0440\u0438\u0437\u043d\u0430\u043a\u0430\u043c (\u043a\u043e\u043b\u0438\u0447\u0435\u0441\u0442\u0432\u043e, \u0444\u043e\u0440\u043c\u0430, \u0446\u0432\u0435\u0442 \u0438 \u0437\u0430\u043b\u0438\u0432\u043a\u0430), \u0438 \u0443 \u043a\u0430\u0436\u0434\u043e\u0433\u043e \u043f\u0440\u0438\u0437\u043d\u0430\u043a\u0430 \u0442\u0440\u0438 \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u0430. \u0417\u0430\u0434\u0430\u0447\u0430 \u2014 \u043e\u043a\u0438\u043d\u0443\u0442\u044c \u0432\u0437\u0433\u043b\u044f\u0434\u043e\u043c \u043a\u0430\u0440\u0442\u044b \u043d\u0430 \u0441\u0442\u043e\u043b\u0435 \u0438 \u043d\u0430\u0439\u0442\u0438 \u0432\u0435\u0440\u043d\u0443\u044e \"\u0442\u0440\u043e\u0439\u043a\u0443\": \u043f\u043e \u043a\u0430\u0436\u0434\u043e\u043c\u0443 \u0438\u0437 \u0447\u0435\u0442\u044b\u0440\u0451\u0445 \u043f\u0440\u0438\u0437\u043d\u0430\u043a\u043e\u0432 \u0442\u0440\u0438 \u043a\u0430\u0440\u0442\u044b \u0434\u043e\u043b\u0436\u043d\u044b \u0431\u044b\u0442\u044c \u043b\u0438\u0431\u043e \u0432\u0441\u0435 \u043e\u0434\u0438\u043d\u0430\u043a\u043e\u0432\u044b\u043c\u0438, \u043b\u0438\u0431\u043e \u0432\u0441\u0435 \u0440\u0430\u0437\u043d\u044b\u043c\u0438, \u0430 \u0441\u043e\u0447\u0435\u0442\u0430\u043d\u0438\u0435 \"\u0434\u0432\u0435 \u0442\u0430\u043a\u0438\u0445 \u0438 \u043e\u0434\u043d\u0430 \u0434\u0440\u0443\u0433\u0430\u044f\" \u043d\u0435\u0434\u043e\u043f\u0443\u0441\u0442\u0438\u043c\u043e.",benefit:"\u0422\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0439 \u043f\u043e\u0438\u0441\u043a \u0438 \u0441\u0432\u044f\u0437\u044b\u0432\u0430\u043d\u0438\u0435 \u043f\u0440\u0438\u0437\u043d\u0430\u043a\u043e\u0432 \u043d\u0430 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c, \u0430 \u0437\u0430\u043e\u0434\u043d\u043e \u0442\u0443 \u0447\u0430\u0441\u0442\u044c \u0440\u0430\u0431\u043e\u0447\u0435\u0439 \u043f\u0430\u043c\u044f\u0442\u0438, \u0447\u0442\u043e \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0435\u0442 \u043f\u0440\u0430\u0432\u0438\u043b\u0430: \u0432\u044b \u0434\u0435\u0440\u0436\u0438\u0442\u0435 \u0432 \u0433\u043e\u043b\u043e\u0432\u0435 \u0447\u0435\u0442\u044b\u0440\u0435 \u0443\u0441\u043b\u043e\u0432\u0438\u044f \u0438 \u043f\u0440\u043e\u0432\u0435\u0440\u044f\u0435\u0442\u0435 \u0438\u0445 \u0441\u0440\u0430\u0437\u0443 \u043f\u043e \u0442\u0440\u0451\u043c \u043a\u0430\u0440\u0442\u0430\u043c. \u041f\u043e\u0434\u043a\u043b\u044e\u0447\u0430\u0435\u0442\u0441\u044f \u0438 \u043a\u043e\u0433\u043d\u0438\u0442\u0438\u0432\u043d\u0430\u044f \u0433\u0438\u0431\u043a\u043e\u0441\u0442\u044c \u2014 \u0432\u044b \u043f\u043e\u0441\u0442\u043e\u044f\u043d\u043d\u043e \u043e\u0442\u0431\u0440\u0430\u0441\u044b\u0432\u0430\u0435\u0442\u0435 \u043d\u0435\u043f\u043e\u0434\u0445\u043e\u0434\u044f\u0449\u0443\u044e \u0442\u0440\u043e\u0439\u043a\u0443 \u0438 \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0430\u0435\u0442\u0435\u0441\u044c \u043d\u0430 \u043d\u043e\u0432\u0443\u044e.",history:"\u0418\u0433\u0440\u0430 \u0432\u044b\u0440\u043e\u0441\u043b\u0430 \u0438\u0437 \u0441\u0438\u0441\u0442\u0435\u043c\u044b \u043f\u043e\u043c\u0435\u0442\u043e\u043a, \u043a\u043e\u0442\u043e\u0440\u043e\u0439 \u0433\u0435\u043d\u0435\u0442\u0438\u043a \u043e\u0442\u0441\u043b\u0435\u0436\u0438\u0432\u0430\u043b\u0430, \u043a\u0430\u043a\u0438\u0435 \u043f\u0440\u0438\u0437\u043d\u0430\u043a\u0438 \u0432\u0441\u0442\u0440\u0435\u0447\u0430\u044e\u0442\u0441\u044f \u0432 \u0435\u0451 \u0434\u0430\u043d\u043d\u044b\u0445, \u0430 \u043f\u043e\u0442\u043e\u043c \u043f\u0440\u0435\u0432\u0440\u0430\u0442\u0438\u043b\u0430\u0441\u044c \u0432 \u043a\u0430\u0440\u0442\u043e\u0447\u043d\u0443\u044e \u0438\u0433\u0440\u0443, \u0432 \u043a\u043e\u0442\u043e\u0440\u0443\u044e \u0438\u0433\u0440\u0430\u043b\u0438 \u0432 \u043b\u0430\u0431\u043e\u0440\u0430\u0442\u043e\u0440\u0438\u0438 \u0438 \u0441 \u0434\u0440\u0443\u0437\u044c\u044f\u043c\u0438. \u0412 \u043f\u0440\u043e\u0434\u0430\u0436\u0443 \u043e\u043d\u0430 \u0432\u044b\u0448\u043b\u0430 \u0432 1991 \u0433\u043e\u0434\u0443, \u0432 \u0442\u043e\u043c \u0436\u0435 \u0433\u043e\u0434\u0443 \u043f\u043e\u043b\u0443\u0447\u0438\u043b\u0430 \u043f\u0440\u0435\u043c\u0438\u044e Mensa Select \u043e\u0442 \u0430\u043c\u0435\u0440\u0438\u043a\u0430\u043d\u0441\u043a\u043e\u0439 Mensa \u0438 \u0441 \u0442\u0435\u0445 \u043f\u043e\u0440 \u043f\u0440\u0438\u0436\u0438\u043b\u0430\u0441\u044c \u043d\u0430 \u0443\u0440\u043e\u043a\u0430\u0445 \u043c\u0430\u0442\u0435\u043c\u0430\u0442\u0438\u043a\u0438 \u0438 \u0432 \u043a\u0440\u0443\u0433\u0430\u0445 \u043b\u044e\u0431\u0438\u0442\u0435\u043b\u0435\u0439 \u0433\u043e\u043b\u043e\u0432\u043e\u043b\u043e\u043c\u043e\u043a \u2014 \u043e\u0442\u0447\u0430\u0441\u0442\u0438 \u043f\u043e\u0442\u043e\u043c\u0443, \u0447\u0442\u043e \u0435\u0451 \u0443\u0441\u0442\u0440\u043e\u0439\u0441\u0442\u0432\u043e \u043a\u0440\u0430\u0441\u0438\u0432\u043e \u043b\u043e\u0436\u0438\u0442\u0441\u044f \u043d\u0430 \u043a\u043e\u043d\u0435\u0447\u043d\u0443\u044e \u0433\u0435\u043e\u043c\u0435\u0442\u0440\u0438\u044e.",creator:"\u0421\u043e\u0437\u0434\u0430\u043d\u0430 \u0433\u0435\u043d\u0435\u0442\u0438\u043a\u043e\u043c \u041c\u0430\u0440\u0448\u0435\u0439 \u0414\u0436\u0438\u043d \u0424\u0430\u043b\u044c\u043a\u043e \u0432 1974 \u0433\u043e\u0434\u0443, \u043a\u043e\u0433\u0434\u0430 \u043e\u043d\u0430 \u0437\u0430\u043d\u0438\u043c\u0430\u043b\u0430\u0441\u044c \u0433\u0435\u043d\u0435\u0442\u0438\u043a\u043e\u0439 \u0432 \u041a\u0435\u043c\u0431\u0440\u0438\u0434\u0436\u0435 (\u0410\u043d\u0433\u043b\u0438\u044f), \u0438 \u0432\u044b\u043f\u0443\u0449\u0435\u043d\u0430 \u0435\u0451 \u043a\u043e\u043c\u043f\u0430\u043d\u0438\u0435\u0439 Set Enterprises \u0432 1991-\u043c. \u0422\u0430\u043a \u0447\u0442\u043e, \u0432 \u043e\u0442\u043b\u0438\u0447\u0438\u0435 \u043e\u0442 \u043c\u043d\u043e\u0433\u0438\u0445 \u0430\u0431\u0441\u0442\u0440\u0430\u043a\u0442\u043d\u044b\u0445 \u0433\u043e\u043b\u043e\u0432\u043e\u043b\u043e\u043c\u043e\u043a, \u0443 SET \u0435\u0441\u0442\u044c \u043a\u043e\u043d\u043a\u0440\u0435\u0442\u043d\u044b\u0439 \u0438 \u0445\u043e\u0440\u043e\u0448\u043e \u0437\u0430\u0434\u043e\u043a\u0443\u043c\u0435\u043d\u0442\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u044b\u0439 \u0430\u0432\u0442\u043e\u0440.",methods:"\u0412\u044b\u0431\u0435\u0440\u0438\u0442\u0435 \u043e\u0434\u0438\u043d \u043f\u0440\u0438\u0437\u043d\u0430\u043a, \u043d\u0430\u043f\u0440\u0438\u043c\u0435\u0440 \u0446\u0432\u0435\u0442, \u0438 \u043c\u044b\u0441\u043b\u0435\u043d\u043d\u043e \u0440\u0430\u0437\u0431\u0435\u0439\u0442\u0435 \u0441\u0442\u043e\u043b \u043d\u0430 \u0433\u0440\u0443\u043f\u043f\u044b \u0435\u0449\u0451 \u0434\u043e \u043f\u043e\u0438\u0441\u043a\u0430, \u0430 \u043d\u0435 \u0441\u0440\u0430\u0432\u043d\u0438\u0432\u0430\u0439\u0442\u0435 \u0441\u043b\u0443\u0447\u0430\u0439\u043d\u044b\u0435 \u043f\u0430\u0440\u044b. \u041e\u043f\u0438\u0440\u0430\u0439\u0442\u0435\u0441\u044c \u043d\u0430 \u043f\u0440\u0430\u0432\u0438\u043b\u043e: \u043b\u044e\u0431\u044b\u0435 \u0434\u0432\u0435 \u043a\u0430\u0440\u0442\u044b \u043e\u0434\u043d\u043e\u0437\u043d\u0430\u0447\u043d\u043e \u0437\u0430\u0434\u0430\u044e\u0442 \u0435\u0434\u0438\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u0443\u044e \u0442\u0440\u0435\u0442\u044c\u044e, \u0434\u043e\u043f\u043e\u043b\u043d\u044f\u044e\u0449\u0443\u044e \u0442\u0440\u043e\u0439\u043a\u0443, \u043f\u043e\u044d\u0442\u043e\u043c\u0443, \u0437\u0430\u0446\u0435\u043f\u0438\u0432\u0448\u0438\u0441\u044c \u0437\u0430 \u0434\u0432\u0435 \u043a\u0430\u0440\u0442\u044b, \u043e\u0441\u0442\u0430\u0451\u0442\u0441\u044f \u043b\u0438\u0448\u044c \u043f\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u0438\u0442\u044c \u0438 \u043d\u0430\u0439\u0442\u0438 \u044d\u0442\u043e\u0433\u043e \u043d\u0435\u0434\u043e\u0441\u0442\u0430\u044e\u0449\u0435\u0433\u043e \"\u043f\u0430\u0440\u0442\u043d\u0451\u0440\u0430\". \u0417\u0430\u0441\u0442\u0430\u0432\u043b\u044f\u0439\u0442\u0435 \u0441\u0435\u0431\u044f \u043f\u0440\u043e\u0432\u0435\u0440\u044f\u0442\u044c \u0432\u0441\u0435 \u0447\u0435\u0442\u044b\u0440\u0435 \u043f\u0440\u0438\u0437\u043d\u0430\u043a\u0430 \u043f\u0435\u0440\u0435\u0434 \u0442\u0435\u043c, \u043a\u0430\u043a \u043d\u0430\u0437\u0432\u0430\u0442\u044c \u0442\u0440\u043e\u0439\u043a\u0443: \u043f\u0440\u0438 \u043f\u043e\u0441\u043f\u0435\u0448\u043d\u043e\u0439 \u043e\u0448\u0438\u0431\u043a\u0435 \u043e\u0431\u044b\u0447\u043d\u043e \u0443\u043f\u0443\u0441\u043a\u0430\u044e\u0442 \u0438\u043c\u0435\u043d\u043d\u043e \u0437\u0430\u043b\u0438\u0432\u043a\u0443.",duration:"\u041b\u0443\u0447\u0448\u0435 \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u043c\u0438 \u0447\u0430\u0441\u0442\u044b\u043c\u0438 \u0437\u0430\u0445\u043e\u0434\u0430\u043c\u0438: \u043f\u043e \u043f\u044f\u0442\u044c-\u043f\u044f\u0442\u043d\u0430\u0434\u0446\u0430\u0442\u044c \u043c\u0438\u043d\u0443\u0442 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0440\u0430\u0437 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e. \u041e\u0441\u0442\u0430\u043d\u0430\u0432\u043b\u0438\u0432\u0430\u0439\u0442\u0435\u0441\u044c, \u043a\u043e\u0433\u0434\u0430 \u043f\u043e\u0438\u0441\u043a \u0437\u0430\u043c\u0435\u0434\u043b\u044f\u0435\u0442\u0441\u044f \u0438 \u043b\u0435\u0437\u0443\u0442 \u043e\u0448\u0438\u0431\u043a\u0438, \u2014 \u0443\u043f\u043e\u0440\u0441\u0442\u0432\u043e\u0432\u0430\u0442\u044c \u043d\u0430 \u0443\u0441\u0442\u0430\u043b\u043e\u0441\u0442\u0438 \u0437\u043d\u0430\u0447\u0438\u0442 \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u0440\u0430\u0437\u0434\u0440\u0430\u0436\u0435\u043d\u0438\u0435, \u0430 \u043d\u0435 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c.",research:"\u0414\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432\u0430 \u043a\u0440\u0435\u043f\u0447\u0435 \u0432\u0441\u0435\u0433\u043e \u0440\u043e\u0432\u043d\u043e \u0434\u043b\u044f \u0442\u043e\u0433\u043e, \u0447\u0435\u0433\u043e \u0438 \u0436\u0434\u0451\u0448\u044c: \u0432\u044b \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u0438 \u0442\u043e\u0447\u043d\u0435\u0435 \u043d\u0430\u0445\u043e\u0434\u0438\u0442\u0435 \u0442\u0440\u043e\u0439\u043a\u0438 \u0438 \u0432 \u0446\u0435\u043b\u043e\u043c \u043b\u0443\u0447\u0448\u0435 \u0441\u043f\u0440\u0430\u0432\u043b\u044f\u0435\u0442\u0435\u0441\u044c \u0441 \u0442\u0430\u043a\u0438\u043c \u043c\u043d\u043e\u0433\u043e\u043f\u0440\u0438\u0437\u043d\u0430\u043a\u043e\u0432\u044b\u043c \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u043c \u043f\u043e\u0438\u0441\u043a\u043e\u043c. \u0423\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043d\u0438\u044f, \u0447\u0442\u043e \u0438\u0433\u0440\u0430 \u043f\u043e\u0434\u043d\u0438\u043c\u0430\u0435\u0442 \u043e\u0431\u0449\u0438\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442, \u0448\u043a\u043e\u043b\u044c\u043d\u044b\u0435 \u043e\u0446\u0435\u043d\u043a\u0438 \u043f\u043e \u043c\u0430\u0442\u0435\u043c\u0430\u0442\u0438\u043a\u0435 \u0438\u043b\u0438 \u043f\u043e\u0432\u0441\u0435\u0434\u043d\u0435\u0432\u043d\u043e\u0435 \u043c\u044b\u0448\u043b\u0435\u043d\u0438\u0435, \u043a\u0443\u0434\u0430 \u0441\u043b\u0430\u0431\u0435\u0435 \u2014 \u044d\u0442\u043e \u0441\u043e\u0433\u043b\u0430\u0441\u0443\u0435\u0442\u0441\u044f \u0441 \u043e\u0431\u0449\u0435\u0439 \u043a\u0430\u0440\u0442\u0438\u043d\u043e\u0439 \u043f\u043e \u043a\u043e\u0433\u043d\u0438\u0442\u0438\u0432\u043d\u044b\u043c \u0442\u0440\u0435\u043d\u0430\u0436\u0451\u0440\u0430\u043c, \u0433\u0434\u0435 \u0431\u043b\u0438\u0436\u043d\u0438\u0439 \u043f\u0435\u0440\u0435\u043d\u043e\u0441 \u0441\u043a\u0440\u043e\u043c\u0435\u043d, \u0430 \u0434\u0430\u043b\u044c\u043d\u0438\u0439 \u043f\u043e \u0431\u043e\u043b\u044c\u0448\u0435\u0439 \u0447\u0430\u0441\u0442\u0438 \u043d\u0435 \u0434\u043e\u043a\u0430\u0437\u0430\u043d, \u0442\u0430\u043a \u0447\u0442\u043e \u043a \u0433\u0440\u043e\u043c\u043a\u0438\u043c \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f\u043c \u0441\u0442\u043e\u0438\u0442 \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u044c\u0441\u044f \u0441\u0434\u0435\u0440\u0436\u0430\u043d\u043d\u043e.",rec:"\u0418\u0433\u0440\u0430\u0439\u0442\u0435 \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u043c\u0438 \u043f\u043e\u0434\u0445\u043e\u0434\u0430\u043c\u0438 \u0438 \u0432\u043e\u0437\u044c\u043c\u0438\u0442\u0435 \u0437\u0430 \u043f\u0440\u0430\u0432\u0438\u043b\u043e \u043f\u0440\u043e\u0432\u0435\u0440\u044f\u0442\u044c \u0432\u0441\u0435 \u0447\u0435\u0442\u044b\u0440\u0435 \u043f\u0440\u0438\u0437\u043d\u0430\u043a\u0430 \u043d\u0430 \u043a\u0430\u0436\u0434\u043e\u0439 \u0442\u0440\u043e\u0439\u043a\u0435, \u0430 \u043d\u0435 \u0442\u043e\u043b\u044c\u043a\u043e \u0442\u0435 \u0434\u0432\u0430, \u0447\u0442\u043e \u0431\u0440\u043e\u0441\u0438\u043b\u0438\u0441\u044c \u0432 \u0433\u043b\u0430\u0437\u0430, \u2014 \u0441\u043d\u0430\u0447\u0430\u043b\u0430 \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u044c, \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u043f\u043e\u0434\u0442\u044f\u043d\u0435\u0442\u0441\u044f \u0441\u043b\u0435\u0434\u043e\u043c.",faq:[["\u0427\u0442\u043e \u0438\u043c\u0435\u043d\u043d\u043e \u0441\u0447\u0438\u0442\u0430\u0435\u0442\u0441\u044f \u0442\u0440\u043e\u0439\u043a\u043e\u0439?","\u0422\u0440\u0438 \u043a\u0430\u0440\u0442\u044b, \u0443 \u043a\u043e\u0442\u043e\u0440\u044b\u0445 \u043a\u0430\u0436\u0434\u044b\u0439 \u0438\u0437 \u0447\u0435\u0442\u044b\u0440\u0451\u0445 \u043f\u0440\u0438\u0437\u043d\u0430\u043a\u043e\u0432 \u2014 \u043a\u043e\u043b\u0438\u0447\u0435\u0441\u0442\u0432\u043e, \u0444\u043e\u0440\u043c\u0430, \u0446\u0432\u0435\u0442 \u0438 \u0437\u0430\u043b\u0438\u0432\u043a\u0430 \u2014 \u043b\u0438\u0431\u043e \u043e\u0434\u0438\u043d\u0430\u043a\u043e\u0432 \u043d\u0430 \u0432\u0441\u0435\u0445 \u0442\u0440\u0451\u0445, \u043b\u0438\u0431\u043e \u0440\u0430\u0437\u043b\u0438\u0447\u0435\u043d \u043d\u0430 \u0432\u0441\u0435\u0445 \u0442\u0440\u0451\u0445. \u0415\u0441\u043b\u0438 \u043f\u043e \u043a\u0430\u043a\u043e\u043c\u0443-\u0442\u043e \u043f\u0440\u0438\u0437\u043d\u0430\u043a\u0443 \u0432\u044b\u0445\u043e\u0434\u0438\u0442 \u0434\u0432\u0435 \u043a\u0430\u0440\u0442\u044b \u043e\u0434\u043d\u043e\u0433\u043e \u0432\u0438\u0434\u0430 \u0438 \u043e\u0434\u043d\u0430 \u0434\u0440\u0443\u0433\u043e\u0433\u043e, \u044d\u0442\u043e \u043d\u0435 \u0442\u0440\u043e\u0439\u043a\u0430."],["\u042f \u0441\u0442\u0430\u043d\u0443 \u0443\u043c\u043d\u0435\u0435 \u0438\u043b\u0438 \u0441\u0438\u043b\u044c\u043d\u0435\u0435 \u0432 \u043c\u0430\u0442\u0435\u043c\u0430\u0442\u0438\u043a\u0435?","\u0427\u0435\u0441\u0442\u043d\u043e \u2014 \u0432 \u043e\u0441\u043d\u043e\u0432\u043d\u043e\u043c \u0432\u044b \u0441\u0442\u0430\u043d\u0435\u0442\u0435 \u0441\u0438\u043b\u044c\u043d\u0435\u0435 \u0432 \u0441\u0430\u043c\u043e\u0439 SET \u0438 \u0432 \u0431\u044b\u0441\u0442\u0440\u043e\u043c \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u043c \u043f\u043e\u0438\u0441\u043a\u0435. \u041d\u0430\u0434\u0451\u0436\u043d\u044b\u0445 \u0434\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432, \u0447\u0442\u043e \u0438\u0433\u0440\u0430 \u043f\u043e\u0432\u044b\u0448\u0430\u0435\u0442 \u043e\u0431\u0449\u0438\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0438\u043b\u0438 \u043e\u0446\u0435\u043d\u043a\u0438 \u043f\u043e \u043c\u0430\u0442\u0435\u043c\u0430\u0442\u0438\u043a\u0435, \u043d\u0435\u0442, \u0445\u043e\u0442\u044f \u044d\u0442\u043e \u0445\u043e\u0440\u043e\u0448\u0430\u044f \u0441\u043e\u0441\u0440\u0435\u0434\u043e\u0442\u043e\u0447\u0435\u043d\u043d\u0430\u044f \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u0430 \u0432 \u0440\u0430\u0441\u043f\u043e\u0437\u043d\u0430\u0432\u0430\u043d\u0438\u0438 \u0437\u0430\u043a\u043e\u043d\u043e\u043c\u0435\u0440\u043d\u043e\u0441\u0442\u0435\u0439, \u0438 \u043e\u043d\u0430 \u043a\u0440\u0430\u0441\u0438\u0432\u043e \u043f\u0435\u0440\u0435\u043a\u043b\u0438\u043a\u0430\u0435\u0442\u0441\u044f \u0441 \u043a\u043e\u043d\u0435\u0447\u043d\u043e\u0439 \u0433\u0435\u043e\u043c\u0435\u0442\u0440\u0438\u0435\u0439."],["\u042f \u0437\u0430\u0432\u0438\u0441\u0430\u044e \u0438 \u043d\u0438\u0447\u0435\u0433\u043e \u043d\u0435 \u043d\u0430\u0445\u043e\u0436\u0443 \u2014 \u0447\u0442\u043e \u043f\u043e\u043c\u043e\u0433\u0430\u0435\u0442?","\u041f\u0435\u0440\u0435\u0441\u0442\u0430\u043d\u044c\u0442\u0435 \u043e\u0445\u0432\u0430\u0442\u044b\u0432\u0430\u0442\u044c \u0432\u0441\u0451 \u0440\u0430\u0437\u043e\u043c. \u0417\u0430\u0444\u0438\u043a\u0441\u0438\u0440\u0443\u0439\u0442\u0435\u0441\u044c \u043d\u0430 \u043e\u0434\u043d\u043e\u043c \u043f\u0440\u0438\u0437\u043d\u0430\u043a\u0435, \u0441\u0433\u0440\u0443\u043f\u043f\u0438\u0440\u0443\u0439\u0442\u0435 \u043f\u043e \u043d\u0435\u043c\u0443 \u043a\u0430\u0440\u0442\u044b, \u0430 \u0434\u0430\u043b\u044c\u0448\u0435 \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0439\u0442\u0435 \u0442\u043e, \u0447\u0442\u043e \u043b\u044e\u0431\u044b\u0435 \u0434\u0432\u0435 \u043a\u0430\u0440\u0442\u044b \u0443\u043a\u0430\u0437\u044b\u0432\u0430\u044e\u0442 \u043d\u0430 \u0435\u0434\u0438\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u0443\u044e \u0434\u043e\u043f\u043e\u043b\u043d\u044f\u044e\u0449\u0443\u044e, \u2014 \u0438 \u0438\u0449\u0438\u0442\u0435 \u0442\u043e\u043b\u044c\u043a\u043e \u0435\u0451."]],variants:"\u0421\u0440\u0435\u0434\u0438 \u0440\u0430\u0441\u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0451\u043d\u043d\u044b\u0445 \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u043e\u0432: \u043e\u0434\u0438\u043d\u043e\u0447\u043d\u044b\u0439 \u0440\u0435\u0436\u0438\u043c \u043d\u0430 \u0432\u0440\u0435\u043c\u044f \u043f\u0440\u043e\u0442\u0438\u0432 \u0447\u0430\u0441\u043e\u0432, \u0431\u044b\u0441\u0442\u0440\u0430\u044f \u043c\u043d\u043e\u0433\u043e\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u0442\u0435\u043b\u044c\u0441\u043a\u0430\u044f \u0433\u043e\u043d\u043a\u0430 \"\u043a\u0442\u043e \u043f\u0435\u0440\u0432\u044b\u0439 \u043d\u0430\u0437\u043e\u0432\u0451\u0442\", \u043e\u0431\u043b\u0435\u0433\u0447\u0451\u043d\u043d\u044b\u0435 \u043a\u043e\u043b\u043e\u0434\u044b \u0431\u0435\u0437 \u0437\u0430\u043b\u0438\u0432\u043a\u0438 (\u0442\u0440\u0438 \u043f\u0440\u0438\u0437\u043d\u0430\u043a\u0430 \u0432\u043c\u0435\u0441\u0442\u043e \u0447\u0435\u0442\u044b\u0440\u0451\u0445) \u0438 \u0440\u0435\u0436\u0438\u043c\u044b-\u0433\u043e\u043b\u043e\u0432\u043e\u043b\u043e\u043c\u043a\u0438, \u0433\u0434\u0435 \u043d\u0443\u0436\u043d\u043e \u0441\u043e\u0441\u0447\u0438\u0442\u0430\u0442\u044c, \u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0442\u0440\u043e\u0435\u043a \u0435\u0441\u0442\u044c \u0432 \u0444\u0438\u043a\u0441\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u043e\u0439 \u0440\u0430\u0441\u043a\u043b\u0430\u0434\u043a\u0435, \u0438\u043b\u0438 \u0433\u0434\u0435 \u0445\u043e\u0442\u044f \u0431\u044b \u043e\u0434\u043d\u0430 \u0442\u0440\u043e\u0439\u043a\u0430 \u0433\u0430\u0440\u0430\u043d\u0442\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u043e \u043f\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442."},en:{about:"SET: Triples is a visual pattern game built on a deck where every card varies on four features (number, shape, colour and shading), each with three values. Your job is to scan the cards on the table and spot a valid \"set\" of three: for each of the four features the three cards must be either all the same or all different, with no two-and-one mix allowed.",benefit:"It trains visual search and feature binding under time pressure, plus the rule-juggling part of working memory, since you hold four conditions in mind and check them across three cards at once. It also leans on cognitive flexibility, because you constantly drop a candidate triple and switch to scanning a fresh one.",history:"The game grew out of a shorthand a geneticist used to track which traits appeared in her data, then turned into a card game played around the lab and among friends. It was published commercially in 1991, won American Mensa's Mensa Select award the same year, and has since become a staple in maths classrooms and puzzle circles, partly because its structure maps neatly onto finite geometry.",creator:"Created by geneticist Marsha Jean Falco in 1974 while she was studying genetics in Cambridge, England, and published by her company Set Enterprises in 1991. So unlike many abstract puzzles, SET has a single, well-documented inventor.",methods:"Pick one feature, say colour, and mentally split the table into groups before hunting, rather than comparing random pairs. Lean on the rule that any two cards determine exactly one third card that completes a set, so once two cards catch your eye you only need to picture and find that one partner. Force yourself to verify all four features before committing, since a fast wrong call usually misses shading.",duration:"Short, frequent rounds work best: five to fifteen minutes at a time, a few times a week. Stop when your search slows and errors creep in, because grinding while fatigued mostly trains frustration, not speed.",research:"Evidence is strongest for exactly what you would expect, you get faster and more accurate at finding sets and at this style of multi-feature visual search. Claims that it lifts general intelligence, school maths grades or everyday reasoning are far weaker, in line with the broader cognitive-training literature where near transfer is modest and far transfer is largely unproven, so treat the grand promises with caution.",rec:"Play in short bursts and commit to checking all four features on every triple, not just the two that jumped out, accuracy first, speed will follow.",faq:[["What exactly counts as a set?","Three cards where each of the four features, number, shape, colour and shading, is either identical on all three or different on all three. If any feature shows two of one kind and one of another, it is not a set."],["Will this make me smarter or better at maths?","Honestly, mostly it makes you better at SET and at fast visual search. There is no solid evidence it raises general intelligence or maths grades, though it is good focused practice for spotting patterns and it ties in nicely with finite geometry."],["I freeze and cannot find anything, what helps?","Stop scanning everything at once. Fix on one feature, group the cards by it, then use the fact that any two cards point to exactly one card that completes the set, and look only for that one."]],variants:"Common variations include a solo timed mode against the clock, a quick \"first to call it\" multiplayer race, easier decks that drop shading to three features, and puzzle modes that ask how many sets exist in a fixed layout or guarantee at least one is present."},es:{about:"SET: Tr\xedos es un juego de patrones visuales basado en una baraja en la que cada carta var\xeda en cuatro rasgos (n\xfamero, forma, color y sombreado), cada uno con tres valores. Tu tarea es escanear las cartas de la mesa y detectar un \"set\" v\xe1lido de tres: para cada uno de los cuatro rasgos las tres cartas deben ser o todas iguales o todas distintas, sin que se permita la mezcla de dos y uno.",benefit:"Entrena la b\xfasqueda visual y la integraci\xf3n de rasgos bajo presi\xf3n de tiempo, adem\xe1s de la parte de la memoria de trabajo que hace malabares con reglas, ya que mantienes cuatro condiciones en mente y las verificas en tres cartas a la vez. Tambi\xe9n se apoya en la flexibilidad cognitiva, porque descartas constantemente un tr\xedo candidato y cambias a escanear uno nuevo.",history:"El juego surgi\xf3 de una notaci\xf3n abreviada que una genetista usaba para registrar qu\xe9 rasgos aparec\xedan en sus datos, y luego se convirti\xf3 en un juego de cartas que se jugaba en el laboratorio y entre amigos. Se public\xf3 comercialmente en 1991, gan\xf3 el premio Mensa Select de la American Mensa ese mismo a\xf1o y desde entonces se ha vuelto un cl\xe1sico en las aulas de matem\xe1ticas y en los c\xedrculos de puzles, en parte porque su estructura encaja con precisi\xf3n en la geometr\xeda finita.",creator:"Creado por la genetista Marsha Jean Falco en 1974, mientras estudiaba gen\xe9tica en Cambridge, Inglaterra, y publicado por su empresa Set Enterprises en 1991. As\xed que, a diferencia de muchos puzles abstractos, SET tiene una \xfanica inventora bien documentada.",methods:"Elige un rasgo, digamos el color, y divide mentalmente la mesa en grupos antes de buscar, en vez de comparar pares al azar. Ap\xf3yate en la regla de que dos cartas cualesquiera determinan exactamente una tercera carta que completa un set, as\xed que en cuanto dos cartas te llamen la atenci\xf3n solo necesitas imaginar y encontrar esa \xfanica compa\xf1era. Obl\xedgate a verificar los cuatro rasgos antes de confirmar, ya que una decisi\xf3n r\xe1pida y equivocada suele pasar por alto el sombreado.",duration:"Las rondas cortas y frecuentes funcionan mejor: de cinco a quince minutos cada vez, unas cuantas veces por semana. Detente cuando tu b\xfasqueda se ralentice y empiecen a colarse errores, porque insistir cansado entrena sobre todo la frustraci\xf3n, no la velocidad.",research:"La evidencia es m\xe1s s\xf3lida justo para lo que cabr\xeda esperar: te vuelves m\xe1s r\xe1pido y preciso encontrando sets y en este estilo de b\xfasqueda visual de m\xfaltiples rasgos. Las afirmaciones de que eleva la inteligencia general, las notas de matem\xe1ticas en la escuela o el razonamiento cotidiano son mucho m\xe1s d\xe9biles, en l\xednea con la literatura m\xe1s amplia sobre entrenamiento cognitivo, donde la transferencia cercana es modesta y la lejana est\xe1 en gran medida sin probar, as\xed que toma con cautela las grandes promesas.",rec:"Juega en r\xe1fagas cortas y comprom\xe9tete a comprobar los cuatro rasgos en cada tr\xedo, no solo los dos que saltaron a la vista: primero la precisi\xf3n, la velocidad vendr\xe1 despu\xe9s.",faq:[["\xbfQu\xe9 cuenta exactamente como un set?","Tres cartas en las que cada uno de los cuatro rasgos \u2014n\xfamero, forma, color y sombreado\u2014 es o id\xe9ntico en las tres o distinto en las tres. Si alg\xfan rasgo muestra dos de un tipo y uno de otro, no es un set."],["\xbfEsto me har\xe1 m\xe1s inteligente o mejor en matem\xe1ticas?","Sinceramente, sobre todo te hace mejor en SET y en la b\xfasqueda visual r\xe1pida. No hay evidencia s\xf3lida de que eleve la inteligencia general ni las notas de matem\xe1ticas, aunque es una buena pr\xe1ctica concentrada para detectar patrones y conecta muy bien con la geometr\xeda finita."],["Me bloqueo y no encuentro nada, \xbfqu\xe9 ayuda?","Deja de escanearlo todo a la vez. F\xedjate en un solo rasgo, agrupa las cartas por \xe9l y luego usa el hecho de que dos cartas cualesquiera apuntan a exactamente una carta que completa el set, y busca solo esa."]],variants:"Entre las variantes habituales est\xe1n un modo individual contrarreloj, una r\xe1pida carrera multijugador de \"el primero que lo cante\", barajas m\xe1s f\xe1ciles que quitan el sombreado y dejan tres rasgos, y modos de puzle que preguntan cu\xe1ntos sets existen en una disposici\xf3n fija o garantizan que hay al menos uno presente."},de:{about:"SET: Triples ist ein visuelles Musterspiel auf Basis eines Kartensatzes, bei dem jede Karte in vier Merkmalen variiert (Anzahl, Form, Farbe und F\xfcllung), jeweils mit drei Auspr\xe4gungen. Deine Aufgabe ist es, die Karten auf dem Tisch zu \xfcberfliegen und ein g\xfcltiges \"Set\" aus drei Karten zu erkennen: Bei jedem der vier Merkmale m\xfcssen die drei Karten entweder alle gleich oder alle verschieden sein, ein Zwei-zu-eins-Mix ist nicht erlaubt.",benefit:"Es trainiert die visuelle Suche und das Merkmalsbinden unter Zeitdruck sowie den regeljonglierenden Teil des Arbeitsged\xe4chtnisses, denn du beh\xe4ltst vier Bedingungen im Kopf und pr\xfcfst sie \xfcber drei Karten gleichzeitig. Es st\xfctzt sich au\xdferdem auf kognitive Flexibilit\xe4t, weil du st\xe4ndig ein Kandidaten-Tripel verwirfst und zum \xdcberfliegen eines neuen wechselst.",history:"Das Spiel entstand aus einer Kurzschreibweise, mit der eine Genetikerin festhielt, welche Merkmale in ihren Daten auftauchten, und wurde dann zu einem Kartenspiel, das im Labor und unter Freunden gespielt wurde. Es wurde 1991 kommerziell ver\xf6ffentlicht, gewann im selben Jahr den Mensa-Select-Preis der American Mensa und ist seitdem ein fester Bestandteil von Mathematik-Klassenr\xe4umen und R\xe4tselkreisen geworden, auch weil sich seine Struktur sauber auf die endliche Geometrie abbilden l\xe4sst.",creator:"Erfunden von der Genetikerin Marsha Jean Falco im Jahr 1974, w\xe4hrend sie in Cambridge, England, Genetik studierte, und 1991 von ihrem Unternehmen Set Enterprises ver\xf6ffentlicht. Anders als viele abstrakte R\xe4tsel hat SET also einen einzelnen, gut dokumentierten Erfinder.",methods:"W\xe4hle ein Merkmal, etwa Farbe, und teile den Tisch im Kopf in Gruppen auf, bevor du suchst, statt zuf\xe4llige Paare zu vergleichen. St\xfctze dich auf die Regel, dass zwei beliebige Karten genau eine dritte Karte bestimmen, die ein Set vervollst\xe4ndigt, sodass du, sobald dir zwei Karten ins Auge fallen, dir nur diesen einen Partner vorstellen und finden musst. Zwinge dich, alle vier Merkmale zu \xfcberpr\xfcfen, bevor du dich festlegst, denn ein schneller Fehlgriff \xfcbersieht meist die F\xfcllung.",duration:"Kurze, h\xe4ufige Runden funktionieren am besten: f\xfcnf bis f\xfcnfzehn Minuten am St\xfcck, ein paar Mal pro Woche. H\xf6r auf, wenn deine Suche langsamer wird und sich Fehler einschleichen, denn ersch\xf6pftes Weitermachen trainiert vor allem Frust, nicht Tempo.",research:"Die Belege sind am st\xe4rksten f\xfcr genau das, was man erwarten w\xfcrde: Du wirst schneller und genauer beim Finden von Sets und bei dieser Art von visueller Mehrmerkmalssuche. Behauptungen, es hebe die allgemeine Intelligenz, die Mathenoten in der Schule oder das allt\xe4gliche Schlussfolgern, sind weit schw\xe4cher, im Einklang mit der breiteren Literatur zum kognitiven Training, in der naher Transfer bescheiden und ferner Transfer weitgehend unbelegt ist, also begegne den gro\xdfen Versprechen mit Vorsicht.",rec:"Spiele in kurzen Sch\xfcben und nimm dir vor, bei jedem Tripel alle vier Merkmale zu pr\xfcfen, nicht nur die zwei, die ins Auge sprangen, Genauigkeit zuerst, das Tempo folgt von selbst.",faq:[["Was genau z\xe4hlt als Set?","Drei Karten, bei denen jedes der vier Merkmale, Anzahl, Form, Farbe und F\xfcllung, entweder auf allen dreien identisch oder auf allen dreien verschieden ist. Zeigt irgendein Merkmal zweimal die eine und einmal die andere Auspr\xe4gung, ist es kein Set."],["Macht mich das kl\xfcger oder besser in Mathe?","Ehrlich gesagt macht es dich vor allem besser in SET und bei der schnellen visuellen Suche. Es gibt keinen soliden Beleg, dass es die allgemeine Intelligenz oder Mathenoten hebt, auch wenn es gutes, konzentriertes Training f\xfcr das Erkennen von Mustern ist und sich sch\xf6n mit der endlichen Geometrie verzahnt."],["Ich erstarre und finde nichts, was hilft?","H\xf6r auf, alles auf einmal zu \xfcberfliegen. Fixiere dich auf ein Merkmal, gruppiere die Karten danach, und nutze dann die Tatsache, dass zwei beliebige Karten auf genau eine Karte verweisen, die das Set vervollst\xe4ndigt, und suche nur nach dieser einen."]],variants:"\xdcbliche Varianten sind ein Solomodus auf Zeit gegen die Uhr, ein schnelles \"Wer-zuerst-ruft\"-Mehrspielerrennen, leichtere Kartens\xe4tze, die die F\xfcllung weglassen und so auf drei Merkmale reduzieren, sowie R\xe4tselmodi, die fragen, wie viele Sets in einer festen Anordnung existieren, oder garantieren, dass mindestens eines vorhanden ist."},pt:{about:"SET: Trios \xe9 um jogo de padr\xf5es visuais baseado num baralho em que cada carta varia em quatro caracter\xedsticas (n\xfamero, forma, cor e preenchimento), cada uma com tr\xeas valores. Sua tarefa \xe9 varrer as cartas na mesa e localizar um \"set\" v\xe1lido de tr\xeas: para cada uma das quatro caracter\xedsticas, as tr\xeas cartas devem ser ou todas iguais ou todas diferentes, sem misturas do tipo duas e uma.",benefit:"Ele treina a busca visual e a integra\xe7\xe3o de caracter\xedsticas sob press\xe3o de tempo, al\xe9m da parte da mem\xf3ria de trabalho que faz malabarismo com regras, j\xe1 que voc\xea segura quatro condi\xe7\xf5es na cabe\xe7a e as confere em tr\xeas cartas ao mesmo tempo. Tamb\xe9m se apoia na flexibilidade cognitiva, porque voc\xea descarta um trio candidato a todo instante e parte para varrer outro novo.",history:"O jogo nasceu de uma nota\xe7\xe3o que uma geneticista usava para acompanhar quais tra\xe7os apareciam em seus dados, e depois virou um jogo de cartas disputado no laborat\xf3rio e entre amigos. Foi publicado comercialmente em 1991, ganhou o pr\xeamio Mensa Select da Mensa Americana no mesmo ano e desde ent\xe3o se tornou item b\xe1sico em salas de aula de matem\xe1tica e em rodas de quebra-cabe\xe7as, em parte porque sua estrutura se mapeia bem na geometria finita.",creator:"Criado pela geneticista Marsha Jean Falco em 1974, enquanto estudava gen\xe9tica em Cambridge, na Inglaterra, e publicado por sua empresa, a Set Enterprises, em 1991. Ou seja, ao contr\xe1rio de muitos quebra-cabe\xe7as abstratos, o SET tem uma inventora \xfanica e bem documentada.",methods:"Escolha uma caracter\xedstica, digamos a cor, e divida a mesa mentalmente em grupos antes de sair ca\xe7ando, em vez de comparar pares aleat\xf3rios. Apoie-se na regra de que quaisquer duas cartas determinam exatamente uma terceira que completa um set, de modo que, assim que duas cartas chamarem sua aten\xe7\xe3o, basta imaginar e procurar essa \xfanica parceira. Force-se a verificar as quatro caracter\xedsticas antes de confirmar, pois um palpite r\xe1pido e errado costuma escorregar no preenchimento.",duration:"Rodadas curtas e frequentes funcionam melhor: de cinco a quinze minutos por vez, algumas vezes por semana. Pare quando sua busca ficar mais lenta e os erros come\xe7arem a aparecer, porque insistir cansado treina mais a frustra\xe7\xe3o do que a velocidade.",research:"As evid\xeancias s\xe3o mais fortes exatamente para o esperado: voc\xea fica mais r\xe1pido e mais preciso em encontrar sets e nesse estilo de busca visual com v\xe1rias caracter\xedsticas. Alega\xe7\xf5es de que ele eleva a intelig\xeancia geral, as notas de matem\xe1tica na escola ou o racioc\xednio do dia a dia s\xe3o bem mais fracas, em linha com a literatura mais ampla de treino cognitivo, em que a transfer\xeancia pr\xf3xima \xe9 modesta e a transfer\xeancia distante \xe9 em grande parte n\xe3o comprovada, ent\xe3o trate as grandes promessas com cautela.",rec:"Jogue em surtos curtos e comprometa-se a checar as quatro caracter\xedsticas em todo trio, n\xe3o s\xf3 as duas que saltaram aos olhos: precis\xe3o primeiro, a velocidade vem depois.",faq:[["O que exatamente conta como um set?","Tr\xeas cartas em que cada uma das quatro caracter\xedsticas, n\xfamero, forma, cor e preenchimento, \xe9 ou id\xeantica nas tr\xeas ou diferente nas tr\xeas. Se qualquer caracter\xedstica mostrar duas de um tipo e uma de outro, n\xe3o \xe9 um set."],["Isso vai me deixar mais inteligente ou melhor em matem\xe1tica?","Honestamente, na maior parte das vezes s\xf3 te deixa melhor no SET e na busca visual r\xe1pida. N\xe3o h\xe1 evid\xeancia s\xf3lida de que eleve a intelig\xeancia geral ou as notas de matem\xe1tica, embora seja uma boa pr\xe1tica focada para detectar padr\xf5es e tenha uma liga\xe7\xe3o bonita com a geometria finita."],["Eu travo e n\xe3o consigo achar nada, o que ajuda?","Pare de varrer tudo de uma vez. Fixe-se numa caracter\xedstica, agrupe as cartas por ela e ent\xe3o use o fato de que quaisquer duas cartas apontam para exatamente uma carta que completa o set, e procure s\xf3 por essa."]],variants:"Varia\xe7\xf5es comuns incluem um modo solo cronometrado contra o rel\xf3gio, uma corrida multiplayer do tipo \"o primeiro a cantar\", baralhos mais f\xe1ceis que abrem m\xe3o do preenchimento e ficam em tr\xeas caracter\xedsticas, e modos de quebra-cabe\xe7a que perguntam quantos sets existem num arranjo fixo ou garantem que ao menos um esteja presente."},hi:{about:"SET: Triples \u090f\u0915 \u0926\u0943\u0936\u094d\u092f-\u092a\u0948\u091f\u0930\u094d\u0928 \u0916\u0947\u0932 \u0939\u0948 \u091c\u094b \u0910\u0938\u0940 \u0924\u093e\u0936 \u0915\u0940 \u0917\u0921\u094d\u0921\u0940 \u092a\u0930 \u092c\u0928\u093e \u0939\u0948 \u091c\u0939\u093e\u0901 \u0939\u0930 \u092a\u0924\u094d\u0924\u093e \u091a\u093e\u0930 \u0935\u093f\u0936\u0947\u0937\u0924\u093e\u0913\u0902 (\u0938\u0902\u0916\u094d\u092f\u093e, \u0906\u0915\u093e\u0930, \u0930\u0902\u0917 \u0914\u0930 \u091b\u093e\u092f\u093e\u0902\u0915\u0928) \u092a\u0930 \u092c\u0926\u0932\u0924\u093e \u0939\u0948, \u0914\u0930 \u0939\u0930 \u0935\u093f\u0936\u0947\u0937\u0924\u093e \u0915\u0947 \u0924\u0940\u0928 \u092e\u093e\u0928 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902\u0964 \u0906\u092a\u0915\u093e \u0915\u093e\u092e \u092e\u0947\u091c\u093c \u092a\u0930 \u0930\u0916\u0947 \u092a\u0924\u094d\u0924\u094b\u0902 \u0915\u094b \u0916\u0902\u0917\u093e\u0932\u0915\u0930 \u0924\u0940\u0928 \u0915\u093e \u090f\u0915 \u0935\u0948\u0927 \"\u0938\u0947\u091f\" \u0916\u094b\u091c\u0928\u093e \u0939\u0948: \u091a\u093e\u0930\u094b\u0902 \u0935\u093f\u0936\u0947\u0937\u0924\u093e\u0913\u0902 \u092e\u0947\u0902 \u0938\u0947 \u0939\u0930 \u090f\u0915 \u0915\u0947 \u0932\u093f\u090f \u0924\u0940\u0928\u094b\u0902 \u092a\u0924\u094d\u0924\u0947 \u092f\u093e \u0924\u094b \u092c\u093f\u0932\u0915\u0941\u0932 \u090f\u0915 \u091c\u0948\u0938\u0947 \u0939\u094b\u0902 \u092f\u093e \u0924\u0940\u0928\u094b\u0902 \u090f\u0915\u0926\u092e \u0905\u0932\u0917, \u0926\u094b-\u0914\u0930-\u090f\u0915 \u0915\u093e \u092e\u0947\u0932 \u0928\u0939\u0940\u0902 \u091a\u0932\u0947\u0917\u093e\u0964",benefit:"\u092f\u0939 \u0938\u092e\u092f \u0915\u0947 \u0926\u092c\u093e\u0935 \u092e\u0947\u0902 \u0926\u0943\u0936\u094d\u092f-\u0916\u094b\u091c \u0914\u0930 \u0935\u093f\u0936\u0947\u0937\u0924\u093e-\u091c\u094b\u0921\u093c\u093e\u0928 \u0915\u094b \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u093f\u0924 \u0915\u0930\u0924\u093e \u0939\u0948, \u0938\u093e\u0925 \u0939\u0940 \u0935\u0930\u094d\u0915\u093f\u0902\u0917 \u092e\u0947\u092e\u094b\u0930\u0940 \u0915\u093e \u0928\u093f\u092f\u092e-\u0938\u0902\u092d\u093e\u0932\u0928\u0947 \u0935\u093e\u0932\u093e \u0939\u093f\u0938\u094d\u0938\u093e \u092d\u0940, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u0906\u092a \u091a\u093e\u0930 \u0936\u0930\u094d\u0924\u0947\u0902 \u0926\u093f\u092e\u093e\u0917 \u092e\u0947\u0902 \u0925\u093e\u092e\u0947 \u0930\u0916\u0924\u0947 \u0939\u0948\u0902 \u0914\u0930 \u090f\u0915 \u0938\u093e\u0925 \u0924\u0940\u0928 \u092a\u0924\u094d\u0924\u094b\u0902 \u092a\u0930 \u0909\u0928\u094d\u0939\u0947\u0902 \u091c\u093e\u0901\u091a\u0924\u0947 \u0939\u0948\u0902\u0964 \u092f\u0939 \u0938\u0902\u091c\u094d\u091e\u093e\u0928\u093e\u0924\u094d\u092e\u0915 \u0932\u091a\u0940\u0932\u0947\u092a\u0928 \u092a\u0930 \u092d\u0940 \u091f\u093f\u0915\u093e \u0939\u0948, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u0906\u092a \u0932\u0917\u093e\u0924\u093e\u0930 \u0915\u093f\u0938\u0940 \u0938\u0902\u092d\u093e\u0935\u093f\u0924 \u0924\u093f\u0915\u0921\u093c\u0940 \u0915\u094b \u091b\u094b\u0921\u093c\u0915\u0930 \u0915\u093f\u0938\u0940 \u0928\u0908 \u0924\u093f\u0915\u0921\u093c\u0940 \u0915\u0940 \u0916\u094b\u091c \u092a\u0930 \u092a\u0932\u091f \u091c\u093e\u0924\u0947 \u0939\u0948\u0902\u0964",history:"\u092f\u0939 \u0916\u0947\u0932 \u0909\u0938 \u0938\u0902\u0915\u094d\u0937\u0947\u092a-\u0938\u0902\u0915\u0947\u0924\u0928 \u0938\u0947 \u0928\u093f\u0915\u0932\u093e \u091c\u094b \u090f\u0915 \u0906\u0928\u0941\u0935\u0902\u0936\u093f\u0915\u0940\u0935\u093f\u0926\u094d \u092f\u0939 \u0926\u0930\u094d\u091c \u0915\u0930\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0915\u0930\u0924\u0940 \u0925\u0940\u0902 \u0915\u093f \u0909\u0928\u0915\u0947 \u0906\u0901\u0915\u0921\u093c\u094b\u0902 \u092e\u0947\u0902 \u0915\u094c\u0928-\u0915\u094c\u0928 \u0938\u0947 \u0932\u0915\u094d\u0937\u0923 \u0926\u093f\u0916\u0947, \u092b\u093f\u0930 \u092f\u0939 \u092a\u094d\u0930\u092f\u094b\u0917\u0936\u093e\u0932\u093e \u092e\u0947\u0902 \u0914\u0930 \u0926\u094b\u0938\u094d\u0924\u094b\u0902 \u0915\u0947 \u092c\u0940\u091a \u0916\u0947\u0932\u093e \u091c\u093e\u0928\u0947 \u0935\u093e\u0932\u093e \u0924\u093e\u0936 \u0915\u093e \u0916\u0947\u0932 \u092c\u0928 \u0917\u092f\u093e\u0964 \u0907\u0938\u0947 1991 \u092e\u0947\u0902 \u0935\u094d\u092f\u093e\u0935\u0938\u093e\u092f\u093f\u0915 \u0930\u0942\u092a \u0938\u0947 \u092a\u094d\u0930\u0915\u093e\u0936\u093f\u0924 \u0915\u093f\u092f\u093e \u0917\u092f\u093e, \u0909\u0938\u0940 \u0938\u093e\u0932 \u0907\u0938\u0928\u0947 \u0905\u092e\u0947\u0930\u093f\u0915\u0928 \u092e\u0947\u0928\u094d\u0938\u093e \u0915\u093e Mensa Select \u092a\u0941\u0930\u0938\u094d\u0915\u093e\u0930 \u091c\u0940\u0924\u093e, \u0914\u0930 \u0924\u092c \u0938\u0947 \u092f\u0939 \u0917\u0923\u093f\u0924 \u0915\u0940 \u0915\u0915\u094d\u0937\u093e\u0913\u0902 \u0914\u0930 \u092a\u0939\u0947\u0932\u0940-\u092e\u0902\u0921\u0932\u093f\u092f\u094b\u0902 \u0915\u093e \u0905\u0928\u093f\u0935\u093e\u0930\u094d\u092f \u0939\u093f\u0938\u094d\u0938\u093e \u092c\u0928 \u0917\u092f\u093e \u0939\u0948, \u0915\u0941\u091b \u0939\u0926 \u0924\u0915 \u0907\u0938\u0932\u093f\u090f \u0915\u093f \u0907\u0938\u0915\u0940 \u0938\u0902\u0930\u091a\u0928\u093e \u0938\u091f\u0940\u0915 \u0930\u0942\u092a \u0938\u0947 \u092a\u0930\u093f\u092e\u093f\u0924 \u091c\u094d\u092f\u093e\u092e\u093f\u0924\u093f \u092a\u0930 \u092c\u0948\u0920 \u091c\u093e\u0924\u0940 \u0939\u0948\u0964",creator:"\u0907\u0938\u0947 \u0906\u0928\u0941\u0935\u0902\u0936\u093f\u0915\u0940\u0935\u093f\u0926\u094d \u092e\u093e\u0930\u094d\u0936\u093e \u091c\u0940\u0928 \u092b\u093e\u0932\u094d\u0915\u094b \u0928\u0947 1974 \u092e\u0947\u0902 \u0930\u091a\u093e, \u091c\u092c \u0935\u0947 \u0907\u0902\u0917\u094d\u0932\u0948\u0902\u0921 \u0915\u0947 \u0915\u0948\u092e\u094d\u092c\u094d\u0930\u093f\u091c \u092e\u0947\u0902 \u0906\u0928\u0941\u0935\u0902\u0936\u093f\u0915\u0940 \u092a\u0922\u093c \u0930\u0939\u0940 \u0925\u0940\u0902, \u0914\u0930 \u0909\u0928\u0915\u0940 \u0915\u0902\u092a\u0928\u0940 \u0938\u0947\u091f \u090f\u0902\u091f\u0930\u092a\u094d\u0930\u093e\u0907\u091c\u093c\u0947\u091c\u093c \u0928\u0947 \u0907\u0938\u0947 1991 \u092e\u0947\u0902 \u092a\u094d\u0930\u0915\u093e\u0936\u093f\u0924 \u0915\u093f\u092f\u093e\u0964 \u0907\u0938\u0932\u093f\u090f \u092c\u0939\u0941\u0924-\u0938\u0940 \u0905\u092e\u0942\u0930\u094d\u0924 \u092a\u0939\u0947\u0932\u093f\u092f\u094b\u0902 \u0915\u0947 \u0935\u093f\u092a\u0930\u0940\u0924, SET \u0915\u093e \u090f\u0915 \u0939\u0940, \u092d\u0932\u0940-\u092d\u093e\u0901\u0924\u093f \u092a\u094d\u0930\u0932\u0947\u0916\u093f\u0924 \u0906\u0935\u093f\u0937\u094d\u0915\u093e\u0930\u0915 \u0939\u0948\u0964",methods:"\u090f\u0915 \u0935\u093f\u0936\u0947\u0937\u0924\u093e \u091a\u0941\u0928\u0947\u0902, \u092e\u093e\u0928 \u0932\u0947\u0902 \u0930\u0902\u0917, \u0914\u0930 \u0916\u094b\u091c \u0936\u0941\u0930\u0942 \u0915\u0930\u0928\u0947 \u0938\u0947 \u092a\u0939\u0932\u0947 \u092e\u0947\u091c\u093c \u0915\u094b \u092e\u0928 \u0939\u0940 \u092e\u0928 \u0938\u092e\u0942\u0939\u094b\u0902 \u092e\u0947\u0902 \u092c\u093e\u0901\u091f \u0932\u0947\u0902, \u092c\u091c\u093e\u092f \u0907\u0938\u0915\u0947 \u0915\u093f \u092c\u0947\u0924\u0930\u0924\u0940\u092c \u091c\u094b\u0921\u093c\u0947 \u092e\u093f\u0932\u093e\u0924\u0947 \u0930\u0939\u0947\u0902\u0964 \u0907\u0938 \u0928\u093f\u092f\u092e \u0915\u093e \u0938\u0939\u093e\u0930\u093e \u0932\u0947\u0902 \u0915\u093f \u0915\u094b\u0908 \u092d\u0940 \u0926\u094b \u092a\u0924\u094d\u0924\u0947 \u0920\u0940\u0915 \u090f\u0915 \u0924\u0940\u0938\u0930\u093e \u092a\u0924\u094d\u0924\u093e \u0924\u092f \u0915\u0930 \u0926\u0947\u0924\u0947 \u0939\u0948\u0902 \u091c\u094b \u0938\u0947\u091f \u092a\u0942\u0930\u093e \u0915\u0930\u0924\u093e \u0939\u0948, \u0924\u093e\u0915\u093f \u091c\u092c \u0926\u094b \u092a\u0924\u094d\u0924\u0947 \u0928\u091c\u093c\u0930 \u092e\u0947\u0902 \u0906 \u091c\u093e\u090f\u0901 \u0924\u094b \u0906\u092a\u0915\u094b \u092c\u0938 \u0909\u0938 \u090f\u0915 \u0938\u093e\u0925\u0940 \u0915\u0940 \u0915\u0932\u094d\u092a\u0928\u093e \u0915\u0930\u0915\u0947 \u0909\u0938\u0947 \u0922\u0942\u0901\u0922\u093c\u0928\u093e \u0939\u0948\u0964 \u0924\u092f \u0915\u0930\u0928\u0947 \u0938\u0947 \u092a\u0939\u0932\u0947 \u0916\u093c\u0941\u0926 \u0915\u094b \u091a\u093e\u0930\u094b\u0902 \u0935\u093f\u0936\u0947\u0937\u0924\u093e\u090f\u0901 \u091c\u093e\u0901\u091a\u0928\u0947 \u092a\u0930 \u092e\u091c\u092c\u0942\u0930 \u0915\u0930\u0947\u0902, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u0924\u0947\u091c\u093c\u0940 \u092e\u0947\u0902 \u0926\u093f\u092f\u093e \u0917\u092f\u093e \u0917\u0932\u0924 \u091c\u0935\u093e\u092c \u0906\u092e\u0924\u094c\u0930 \u092a\u0930 \u091b\u093e\u092f\u093e\u0902\u0915\u0928 \u091a\u0942\u0915 \u091c\u093e\u0924\u093e \u0939\u0948\u0964",duration:"\u091b\u094b\u091f\u0947, \u092c\u093e\u0930-\u092c\u093e\u0930 \u0915\u0947 \u0930\u093e\u0909\u0902\u0921 \u0938\u092c\u0938\u0947 \u0905\u091a\u094d\u091b\u0947 \u0930\u0939\u0924\u0947 \u0939\u0948\u0902: \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u0915\u0941\u091b \u092c\u093e\u0930, \u0939\u0930 \u092c\u093e\u0930 \u092a\u093e\u0901\u091a \u0938\u0947 \u092a\u0902\u0926\u094d\u0930\u0939 \u092e\u093f\u0928\u091f\u0964 \u091c\u092c \u0906\u092a\u0915\u0940 \u0916\u094b\u091c \u0927\u0940\u092e\u0940 \u092a\u0921\u093c\u0928\u0947 \u0932\u0917\u0947 \u0914\u0930 \u0917\u0932\u0924\u093f\u092f\u093e\u0901 \u0930\u0947\u0902\u0917\u0928\u0947 \u0932\u0917\u0947\u0902 \u0924\u094b \u0930\u0941\u0915 \u091c\u093e\u090f\u0901, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u0925\u0915\u0915\u0930 \u0930\u0917\u0921\u093c\u0924\u0947 \u0930\u0939\u0928\u0947 \u0938\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e\u0924\u0930 \u0916\u0940\u091d \u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0939\u094b\u0924\u093e \u0939\u0948, \u0930\u092b\u093c\u094d\u0924\u093e\u0930 \u0915\u093e \u0928\u0939\u0940\u0902\u0964",research:"\u092a\u094d\u0930\u092e\u093e\u0923 \u0938\u092c\u0938\u0947 \u0920\u094b\u0938 \u0920\u0940\u0915 \u0909\u0938\u0940 \u092c\u093e\u0924 \u0915\u0947 \u0932\u093f\u090f \u0939\u0948\u0902 \u091c\u093f\u0938\u0915\u0940 \u0906\u092a \u0909\u092e\u094d\u092e\u0940\u0926 \u0915\u0930\u0947\u0902\u0917\u0947 \u2014 \u0906\u092a \u0938\u0947\u091f \u0922\u0942\u0901\u0922\u093c\u0928\u0947 \u0914\u0930 \u0907\u0938 \u0924\u0930\u0939 \u0915\u0940 \u092c\u0939\u0941-\u0935\u093f\u0936\u0947\u0937\u0924\u093e \u0926\u0943\u0936\u094d\u092f-\u0916\u094b\u091c \u092e\u0947\u0902 \u0924\u0947\u091c\u093c \u0914\u0930 \u0938\u091f\u0940\u0915 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902\u0964 \u092f\u0947 \u0926\u093e\u0935\u0947 \u0915\u093f \u0907\u0938\u0938\u0947 \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u092c\u0941\u0926\u094d\u0927\u093f, \u0938\u094d\u0915\u0942\u0932\u0940 \u0917\u0923\u093f\u0924 \u0915\u0947 \u0905\u0902\u0915 \u092f\u093e \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0940 \u0924\u0930\u094d\u0915\u0936\u0915\u094d\u0924\u093f \u092c\u0922\u093c\u0924\u0940 \u0939\u0948, \u0915\u0939\u0940\u0902 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0915\u092e\u091c\u093c\u094b\u0930 \u0939\u0948\u0902, \u091c\u094b \u0935\u094d\u092f\u093e\u092a\u0915 \u0938\u0902\u091c\u094d\u091e\u093e\u0928\u093e\u0924\u094d\u092e\u0915-\u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u0938\u093e\u0939\u093f\u0924\u094d\u092f \u0915\u0947 \u0905\u0928\u0941\u0930\u0942\u092a \u0939\u0948 \u091c\u0939\u093e\u0901 \u0928\u093f\u0915\u091f \u0939\u0938\u094d\u0924\u093e\u0902\u0924\u0930\u0923 \u092e\u093e\u092e\u0942\u0932\u0940 \u0939\u0948 \u0914\u0930 \u0926\u0942\u0930 \u0915\u093e \u0939\u0938\u094d\u0924\u093e\u0902\u0924\u0930\u0923 \u092c\u0921\u093c\u0947 \u092a\u0948\u092e\u093e\u0928\u0947 \u092a\u0930 \u0905\u092a\u094d\u0930\u092e\u093e\u0923\u093f\u0924, \u0907\u0938\u0932\u093f\u090f \u092c\u0921\u093c\u0947-\u092c\u0921\u093c\u0947 \u0935\u093e\u0926\u094b\u0902 \u0915\u094b \u0938\u093e\u0935\u0927\u093e\u0928\u0940 \u0938\u0947 \u0932\u0947\u0902\u0964",rec:"\u091b\u094b\u091f\u0947-\u091b\u094b\u091f\u0947 \u091d\u094b\u0902\u0915\u094b\u0902 \u092e\u0947\u0902 \u0916\u0947\u0932\u0947\u0902 \u0914\u0930 \u0939\u0930 \u0924\u093f\u0915\u0921\u093c\u0940 \u092a\u0930 \u091a\u093e\u0930\u094b\u0902 \u0935\u093f\u0936\u0947\u0937\u0924\u093e\u090f\u0901 \u091c\u093e\u0901\u091a\u0928\u0947 \u0915\u093e \u0938\u0902\u0915\u0932\u094d\u092a \u0932\u0947\u0902, \u0928 \u0915\u093f \u0938\u093f\u0930\u094d\u092b\u093c \u0935\u0947 \u0926\u094b \u091c\u094b \u0906\u0901\u0916 \u092e\u0947\u0902 \u091a\u0922\u093c \u0917\u0908\u0902 \u2014 \u092a\u0939\u0932\u0947 \u0938\u091f\u0940\u0915\u0924\u093e, \u0930\u092b\u093c\u094d\u0924\u093e\u0930 \u0905\u092a\u0928\u0947 \u0906\u092a \u0906 \u091c\u093e\u090f\u0917\u0940\u0964",faq:[["\u0938\u0947\u091f \u0915\u0947 \u0924\u094c\u0930 \u092a\u0930 \u0905\u0938\u0932 \u092e\u0947\u0902 \u0915\u094d\u092f\u093e \u0917\u093f\u0928\u093e \u091c\u093e\u0924\u093e \u0939\u0948?","\u0924\u0940\u0928 \u092a\u0924\u094d\u0924\u0947 \u091c\u0939\u093e\u0901 \u091a\u093e\u0930\u094b\u0902 \u0935\u093f\u0936\u0947\u0937\u0924\u093e\u090f\u0901 \u2014 \u0938\u0902\u0916\u094d\u092f\u093e, \u0906\u0915\u093e\u0930, \u0930\u0902\u0917 \u0914\u0930 \u091b\u093e\u092f\u093e\u0902\u0915\u0928 \u2014 \u092e\u0947\u0902 \u0938\u0947 \u0939\u0930 \u090f\u0915 \u092f\u093e \u0924\u094b \u0924\u0940\u0928\u094b\u0902 \u092a\u0930 \u090f\u0915 \u091c\u0948\u0938\u0940 \u0939\u094b \u092f\u093e \u0924\u0940\u0928\u094b\u0902 \u092a\u0930 \u0905\u0932\u0917\u0964 \u0905\u0917\u0930 \u0915\u094b\u0908 \u0935\u093f\u0936\u0947\u0937\u0924\u093e \u090f\u0915 \u0924\u0930\u0939 \u0915\u0947 \u0926\u094b \u0914\u0930 \u0926\u0942\u0938\u0930\u0940 \u0924\u0930\u0939 \u0915\u093e \u090f\u0915 \u0926\u093f\u0916\u093e\u0924\u0940 \u0939\u0948, \u0924\u094b \u0935\u0939 \u0938\u0947\u091f \u0928\u0939\u0940\u0902 \u0939\u0948\u0964"],["\u0915\u094d\u092f\u093e \u0907\u0938\u0938\u0947 \u092e\u0948\u0902 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u092c\u0941\u0926\u094d\u0927\u093f\u092e\u093e\u0928 \u092f\u093e \u0917\u0923\u093f\u0924 \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u092c\u0928 \u091c\u093e\u090a\u0901\u0917\u093e?","\u0938\u091a \u0915\u0939\u0947\u0902 \u0924\u094b \u091c\u093c\u094d\u092f\u093e\u0926\u093e\u0924\u0930 \u092f\u0939 \u0906\u092a\u0915\u094b SET \u092e\u0947\u0902 \u0914\u0930 \u0924\u0947\u091c\u093c \u0926\u0943\u0936\u094d\u092f-\u0916\u094b\u091c \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u092c\u0928\u093e\u0924\u093e \u0939\u0948\u0964 \u0907\u0938\u0915\u093e \u0915\u094b\u0908 \u0920\u094b\u0938 \u092a\u094d\u0930\u092e\u093e\u0923 \u0928\u0939\u0940\u0902 \u0915\u093f \u092f\u0939 \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u092c\u0941\u0926\u094d\u0927\u093f \u092f\u093e \u0917\u0923\u093f\u0924 \u0915\u0947 \u0905\u0902\u0915 \u092c\u0922\u093c\u093e\u0924\u093e \u0939\u0948, \u0939\u093e\u0932\u093e\u0901\u0915\u093f \u092f\u0939 \u092a\u0948\u091f\u0930\u094d\u0928 \u092a\u0939\u091a\u093e\u0928\u0928\u0947 \u0915\u093e \u0905\u091a\u094d\u091b\u093e \u090f\u0915\u093e\u0917\u094d\u0930 \u0905\u092d\u094d\u092f\u093e\u0938 \u0939\u0948 \u0914\u0930 \u092a\u0930\u093f\u092e\u093f\u0924 \u091c\u094d\u092f\u093e\u092e\u093f\u0924\u093f \u0938\u0947 \u092c\u0922\u093c\u093f\u092f\u093e \u091c\u0941\u0921\u093c\u0924\u093e \u0939\u0948\u0964"],["\u092e\u0948\u0902 \u091c\u0921\u093c \u0939\u094b \u091c\u093e\u0924\u093e \u0939\u0942\u0901 \u0914\u0930 \u0915\u0941\u091b \u0928\u0939\u0940\u0902 \u0922\u0942\u0901\u0922\u093c \u092a\u093e\u0924\u093e, \u0915\u094d\u092f\u093e \u092e\u0926\u0926 \u0915\u0930\u0924\u093e \u0939\u0948?","\u090f\u0915 \u0938\u093e\u0925 \u0938\u092c \u0915\u0941\u091b \u0916\u0902\u0917\u093e\u0932\u0928\u093e \u092c\u0902\u0926 \u0915\u0930\u0947\u0902\u0964 \u090f\u0915 \u0935\u093f\u0936\u0947\u0937\u0924\u093e \u092a\u0930 \u091f\u093f\u0915\u0947\u0902, \u092a\u0924\u094d\u0924\u094b\u0902 \u0915\u094b \u0909\u0938\u0940 \u0915\u0947 \u0939\u093f\u0938\u093e\u092c \u0938\u0947 \u0938\u092e\u0942\u0939\u094b\u0902 \u092e\u0947\u0902 \u092c\u093e\u0901\u091f\u0947\u0902, \u092b\u093f\u0930 \u0907\u0938 \u0924\u0925\u094d\u092f \u0915\u093e \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0915\u0930\u0947\u0902 \u0915\u093f \u0915\u094b\u0908 \u092d\u0940 \u0926\u094b \u092a\u0924\u094d\u0924\u0947 \u0920\u0940\u0915 \u0909\u0938\u0940 \u090f\u0915 \u092a\u0924\u094d\u0924\u0947 \u0915\u0940 \u0913\u0930 \u0907\u0936\u093e\u0930\u093e \u0915\u0930\u0924\u0947 \u0939\u0948\u0902 \u091c\u094b \u0938\u0947\u091f \u092a\u0942\u0930\u093e \u0915\u0930\u0924\u093e \u0939\u0948, \u0914\u0930 \u0915\u0947\u0935\u0932 \u0909\u0938\u0940 \u090f\u0915 \u0915\u094b \u0916\u094b\u091c\u0947\u0902\u0964"]],variants:"\u0906\u092e \u0930\u0942\u092a\u094b\u0902 \u092e\u0947\u0902 \u0918\u0921\u093c\u0940 \u0915\u0947 \u0935\u093f\u0930\u0941\u0926\u094d\u0927 \u090f\u0915\u0932 \u0938\u092e\u092f\u092c\u0926\u094d\u0927 \u092e\u094b\u0921, \"\u092a\u0939\u0932\u0947 \u092c\u094b\u0932\u0928\u0947 \u0935\u093e\u0932\u093e \u091c\u0940\u0924\u0947\" \u0935\u093e\u0932\u0940 \u0924\u094d\u0935\u0930\u093f\u0924 \u092c\u0939\u0941-\u0916\u093f\u0932\u093e\u0921\u093c\u0940 \u0939\u094b\u0921\u093c, \u0906\u0938\u093e\u0928 \u0917\u0921\u094d\u0921\u093f\u092f\u093e\u0901 \u091c\u094b \u091b\u093e\u092f\u093e\u0902\u0915\u0928 \u0939\u091f\u093e\u0915\u0930 \u0924\u0940\u0928 \u0935\u093f\u0936\u0947\u0937\u0924\u093e\u0913\u0902 \u092a\u0930 \u0906 \u091c\u093e\u0924\u0940 \u0939\u0948\u0902, \u0914\u0930 \u092a\u0939\u0947\u0932\u0940 \u092e\u094b\u0921 \u0936\u093e\u092e\u093f\u0932 \u0939\u0948\u0902 \u091c\u094b \u092a\u0942\u091b\u0924\u0947 \u0939\u0948\u0902 \u0915\u093f \u0915\u093f\u0938\u0940 \u0924\u092f \u0938\u091c\u093e\u0935\u091f \u092e\u0947\u0902 \u0915\u093f\u0924\u0928\u0947 \u0938\u0947\u091f \u092e\u094c\u091c\u0942\u0926 \u0939\u0948\u0902 \u092f\u093e \u0915\u092e-\u0938\u0947-\u0915\u092e \u090f\u0915 \u0915\u0947 \u0939\u094b\u0928\u0947 \u0915\u0940 \u0917\u093e\u0930\u0902\u091f\u0940 \u0926\u0947\u0924\u0947 \u0939\u0948\u0902\u0964"},zh:{about:"\u300cSET \u4e09\u8fde\u300d\u662f\u4e00\u6b3e\u89c6\u89c9\u89c4\u5f8b\u6e38\u620f\uff0c\u5b83\u57fa\u4e8e\u4e00\u526f\u6bcf\u5f20\u724c\u90fd\u5728\u56db\u4e2a\u7279\u5f81\uff08\u6570\u91cf\u3001\u5f62\u72b6\u3001\u989c\u8272\u548c\u586b\u5145\uff09\u4e0a\u5404\u6709\u53d8\u5316\u3001\u6bcf\u4e2a\u7279\u5f81\u53c8\u5404\u6709\u4e09\u79cd\u53d6\u503c\u7684\u724c\u7ec4\u3002\u4f60\u7684\u4efb\u52a1\u662f\u626b\u89c6\u684c\u9762\u4e0a\u7684\u724c\uff0c\u627e\u51fa\u4e00\u7ec4\u6709\u6548\u7684\u300c\u4e09\u8fde\u300d\uff1a\u5bf9\u4e8e\u8fd9\u56db\u4e2a\u7279\u5f81\u4e2d\u7684\u6bcf\u4e00\u4e2a\uff0c\u4e09\u5f20\u724c\u8981\u4e48\u5168\u90fd\u76f8\u540c\uff0c\u8981\u4e48\u5168\u90fd\u4e0d\u540c\uff0c\u7edd\u4e0d\u5141\u8bb8\u51fa\u73b0\u300c\u4e24\u5f20\u4e00\u6837\u3001\u4e00\u5f20\u4e0d\u540c\u300d\u7684\u6df7\u642d\u3002",benefit:"\u5b83\u5728\u65f6\u95f4\u538b\u529b\u4e0b\u8bad\u7ec3\u89c6\u89c9\u641c\u7d22\u548c\u7279\u5f81\u7ed1\u5b9a\uff0c\u5916\u52a0\u5de5\u4f5c\u8bb0\u5fc6\u4e2d\u300c\u540c\u65f6\u73a9\u8f6c\u591a\u6761\u89c4\u5219\u300d\u7684\u90a3\u90e8\u5206\u2014\u2014\u56e0\u4e3a\u4f60\u8981\u5728\u8111\u4e2d\u8bb0\u4f4f\u56db\u4e2a\u6761\u4ef6\uff0c\u5e76\u4e00\u6b21\u6027\u5728\u4e09\u5f20\u724c\u4e0a\u9010\u4e00\u6838\u5bf9\u5b83\u4eec\u3002\u5b83\u540c\u6837\u4f9d\u8d56\u8ba4\u77e5\u7075\u6d3b\u6027\uff0c\u56e0\u4e3a\u4f60\u5f97\u4e0d\u65ad\u653e\u5f03\u4e00\u7ec4\u5019\u9009\u4e09\u8fde\uff0c\u8f6c\u800c\u53bb\u626b\u89c6\u65b0\u7684\u4e00\u7ec4\u3002",history:"\u8fd9\u6b3e\u6e38\u620f\u6e90\u81ea\u4e00\u4f4d\u9057\u4f20\u5b66\u5bb6\u7528\u6765\u8bb0\u5f55\u6570\u636e\u4e2d\u51fa\u73b0\u4e86\u54ea\u4e9b\u6027\u72b6\u7684\u901f\u8bb0\u6cd5\uff0c\u540e\u6765\u5728\u5b9e\u9a8c\u5ba4\u91cc\u548c\u670b\u53cb\u4e4b\u95f4\u53d8\u6210\u4e86\u4e00\u6b3e\u7eb8\u724c\u6e38\u620f\u3002\u5b83\u4e8e1991\u5e74\u5546\u4e1a\u51fa\u7248\uff0c\u540c\u5e74\u8d62\u5f97\u4e86\u7f8e\u56fd\u95e8\u8428\u7684\u300cMensa Select\u300d\u5927\u5956\uff0c\u6b64\u540e\u6210\u4e86\u6570\u5b66\u8bfe\u5802\u548c\u8c1c\u9898\u5708\u91cc\u7684\u5e38\u5ba2\u2014\u2014\u90e8\u5206\u539f\u56e0\u5728\u4e8e\u5b83\u7684\u7ed3\u6784\u6070\u597d\u80fd\u5e72\u51c0\u5229\u843d\u5730\u5bf9\u5e94\u5230\u6709\u9650\u51e0\u4f55\u4e0a\u3002",creator:"\u7531\u9057\u4f20\u5b66\u5bb6\u739b\u838e\xb7\u743c\xb7\u6cd5\u5c14\u79d1\uff08Marsha Jean Falco\uff09\u4e8e1974\u5e74\u521b\u4f5c\uff0c\u5f53\u65f6\u5979\u6b63\u5728\u82f1\u56fd\u5251\u6865\u7814\u7a76\u9057\u4f20\u5b66\uff0c\u5e76\u4e8e1991\u5e74\u7531\u5979\u7684\u516c\u53f8 Set Enterprises \u51fa\u7248\u3002\u6240\u4ee5\uff0c\u4e0e\u8bb8\u591a\u62bd\u8c61\u8c1c\u9898\u4e0d\u540c\uff0cSET \u6709\u4e00\u4f4d\u5355\u4e00\u7684\u3001\u8bb0\u8f7d\u7fd4\u5b9e\u7684\u53d1\u660e\u8005\u3002",methods:"\u6311\u4e00\u4e2a\u7279\u5f81\uff0c\u6bd4\u65b9\u8bf4\u989c\u8272\uff0c\u5728\u52a8\u624b\u627e\u4e4b\u524d\u5148\u5728\u8111\u4e2d\u628a\u684c\u9762\u5206\u6210\u82e5\u5e72\u7ec4\uff0c\u800c\u4e0d\u662f\u53bb\u6bd4\u5bf9\u968f\u673a\u7684\u724c\u5bf9\u3002\u8981\u5584\u7528\u8fd9\u6761\u89c4\u5219\uff1a\u4efb\u610f\u4e24\u5f20\u724c\u90fd\u80fd\u552f\u4e00\u786e\u5b9a\u7b2c\u4e09\u5f20\u80fd\u51d1\u6210\u4e09\u8fde\u7684\u724c\uff0c\u6240\u4ee5\u4e00\u65e6\u6709\u4e24\u5f20\u724c\u6293\u4f4f\u4e86\u4f60\u7684\u773c\u7403\uff0c\u4f60\u53ea\u9700\u8981\u60f3\u8c61\u5e76\u627e\u51fa\u90a3\u4e00\u4e2a\u300c\u642d\u6863\u300d\u5373\u53ef\u3002\u5f3a\u8feb\u81ea\u5df1\u5728\u786e\u5b9a\u4e4b\u524d\u6838\u5bf9\u5168\u90e8\u56db\u4e2a\u7279\u5f81\uff0c\u56e0\u4e3a\u4e00\u6b21\u5feb\u901f\u7684\u8bef\u5224\u901a\u5e38\u90fd\u662f\u6f0f\u770b\u4e86\u586b\u5145\u3002",duration:"\u77ed\u800c\u9891\u7e41\u7684\u56de\u5408\u6548\u679c\u6700\u597d\uff1a\u6bcf\u6b21\u4e94\u5230\u5341\u4e94\u5206\u949f\uff0c\u6bcf\u5468\u7ec3\u51e0\u6b21\u3002\u5f53\u4f60\u641c\u7d22\u53d8\u6162\u3001\u9519\u8bef\u5f00\u59cb\u6084\u6084\u5192\u5934\u65f6\u5c31\u505c\u4e0b\u6765\uff0c\u56e0\u4e3a\u5e26\u7740\u75b2\u52b3\u786c\u78d5\uff0c\u78e8\u7ec3\u51fa\u7684\u591a\u534a\u662f\u632b\u8d25\u611f\uff0c\u800c\u4e0d\u662f\u901f\u5ea6\u3002",research:"\u8bc1\u636e\u6700\u624e\u5b9e\u7684\uff0c\u6070\u6070\u662f\u4f60\u80fd\u9884\u6599\u5230\u7684\u90a3\u4e00\u70b9\uff1a\u4f60\u4f1a\u66f4\u5feb\u3001\u66f4\u51c6\u5730\u627e\u51fa\u4e09\u8fde\uff0c\u4e5f\u66f4\u64c5\u957f\u8fd9\u79cd\u591a\u7279\u5f81\u7684\u89c6\u89c9\u641c\u7d22\u3002\u81f3\u4e8e\u8bf4\u5b83\u80fd\u63d0\u5347\u4e00\u822c\u667a\u529b\u3001\u5b66\u6821\u6570\u5b66\u6210\u7ee9\u6216\u65e5\u5e38\u63a8\u7406\uff0c\u8fd9\u7c7b\u8bf4\u6cd5\u5219\u8981\u8584\u5f31\u5f97\u591a\uff0c\u8fd9\u4e0e\u66f4\u5e7f\u6cdb\u7684\u8ba4\u77e5\u8bad\u7ec3\u6587\u732e\u76f8\u7b26\u2014\u2014\u5176\u4e2d\u8fd1\u8fc1\u79fb\u6548\u679c\u6709\u9650\uff0c\u8fdc\u8fc1\u79fb\u5219\u57fa\u672c\u672a\u83b7\u8bc1\u5b9e\uff0c\u6240\u4ee5\u5bf9\u90a3\u4e9b\u5b8f\u5927\u7684\u627f\u8bfa\u8981\u4fdd\u6301\u8c28\u614e\u3002",rec:"\u4ee5\u77ed\u65f6\u6bb5\u51b2\u523a\u7684\u65b9\u5f0f\u6765\u73a9\uff0c\u5e76\u575a\u6301\u5728\u6bcf\u4e00\u7ec4\u4e09\u8fde\u4e0a\u6838\u5bf9\u5168\u90e8\u56db\u4e2a\u7279\u5f81\uff0c\u800c\u4e0d\u53ea\u662f\u90a3\u4e24\u4e2a\u4e00\u773c\u8df3\u51fa\u6765\u7684\u7279\u5f81\u2014\u2014\u51c6\u786e\u4f18\u5148\uff0c\u901f\u5ea6\u81ea\u7136\u4f1a\u8ddf\u4e0a\u6765\u3002",faq:[["\u5230\u5e95\u4ec0\u4e48\u624d\u7b97\u4e00\u7ec4\u300c\u4e09\u8fde\u300d\uff1f","\u4e09\u5f20\u724c\uff0c\u5176\u4e2d\u6570\u91cf\u3001\u5f62\u72b6\u3001\u989c\u8272\u548c\u586b\u5145\u8fd9\u56db\u4e2a\u7279\u5f81\u91cc\u7684\u6bcf\u4e00\u4e2a\uff0c\u8981\u4e48\u5728\u4e09\u5f20\u4e0a\u5b8c\u5168\u76f8\u540c\uff0c\u8981\u4e48\u5728\u4e09\u5f20\u4e0a\u5404\u4e0d\u76f8\u540c\u3002\u53ea\u8981\u6709\u4efb\u4f55\u4e00\u4e2a\u7279\u5f81\u51fa\u73b0\u300c\u4e24\u5f20\u4e00\u79cd\u3001\u4e00\u5f20\u53e6\u4e00\u79cd\u300d\u7684\u60c5\u51b5\uff0c\u5b83\u5c31\u4e0d\u662f\u4e00\u7ec4\u4e09\u8fde\u3002"],["\u8fd9\u4f1a\u8ba9\u6211\u53d8\u806a\u660e\uff0c\u6216\u8005\u6570\u5b66\u53d8\u597d\u5417\uff1f","\u8001\u5b9e\u8bf4\uff0c\u5b83\u4e3b\u8981\u4f1a\u8ba9\u4f60\u66f4\u64c5\u957f\u73a9 SET \u548c\u5feb\u901f\u89c6\u89c9\u641c\u7d22\u3002\u6ca1\u6709\u786e\u51ff\u7684\u8bc1\u636e\u8868\u660e\u5b83\u80fd\u63d0\u5347\u4e00\u822c\u667a\u529b\u6216\u6570\u5b66\u6210\u7ee9\uff0c\u4e0d\u8fc7\u5b83\u786e\u5b9e\u662f\u4e00\u79cd\u5f88\u597d\u7684\u3001\u9488\u5bf9\u53d1\u73b0\u89c4\u5f8b\u7684\u4e13\u6ce8\u8bad\u7ec3\uff0c\u800c\u4e14\u5b83\u4e0e\u6709\u9650\u51e0\u4f55\u5951\u5408\u5f97\u76f8\u5f53\u6f02\u4eae\u3002"],["\u6211\u4f1a\u50f5\u4f4f\uff0c\u4ec0\u4e48\u90fd\u627e\u4e0d\u5230\uff0c\u600e\u4e48\u529e\uff1f","\u522b\u4e00\u4e0b\u5b50\u53bb\u626b\u6240\u6709\u7684\u724c\u3002\u76ef\u4f4f\u4e00\u4e2a\u7279\u5f81\uff0c\u6309\u5b83\u628a\u724c\u5206\u7ec4\uff0c\u7136\u540e\u5229\u7528\u300c\u4efb\u610f\u4e24\u5f20\u724c\u90fd\u552f\u4e00\u6307\u5411\u80fd\u51d1\u6210\u4e09\u8fde\u7684\u90a3\u4e00\u5f20\u724c\u300d\u8fd9\u4e00\u70b9\uff0c\u53ea\u53bb\u627e\u90a3\u4e00\u5f20\u3002"]],variants:"\u5e38\u89c1\u7684\u53d8\u4f53\u5305\u62ec\uff1a\u4e0e\u65f6\u95f4\u8d5b\u8dd1\u7684\u5355\u4eba\u9650\u65f6\u6a21\u5f0f\u3001\u300c\u8c01\u5148\u558a\u51fa\u6765\u8c01\u8d62\u300d\u7684\u5feb\u8282\u594f\u591a\u4eba\u7ade\u8d5b\u3001\u53bb\u6389\u586b\u5145\u3001\u53ea\u5269\u4e09\u4e2a\u7279\u5f81\u7684\u7b80\u5316\u724c\u7ec4\uff0c\u4ee5\u53ca\u4e00\u4e9b\u8c1c\u9898\u6a21\u5f0f\u2014\u2014\u5b83\u4eec\u4f1a\u95ee\u5728\u67d0\u4e2a\u56fa\u5b9a\u5e03\u5c40\u4e2d\u5b58\u5728\u591a\u5c11\u7ec4\u4e09\u8fde\uff0c\u6216\u4fdd\u8bc1\u5176\u4e2d\u81f3\u5c11\u6709\u4e00\u7ec4\u3002"}},simon:{ru:{about:"\u0421\u0442\u0438\u043c\u0443\u043b, \u043d\u0430\u043f\u0440\u0438\u043c\u0435\u0440 \u0446\u0432\u0435\u0442, \u0433\u043e\u0432\u043e\u0440\u0438\u0442, \u043a\u0430\u043a\u0443\u044e \u043a\u043b\u0430\u0432\u0438\u0448\u0443 \u043d\u0430\u0436\u0430\u0442\u044c, \u0430 \u0435\u0433\u043e \u043f\u043e\u0437\u0438\u0446\u0438\u044f \u043d\u0430 \u044d\u043a\u0440\u0430\u043d\u0435 \u043d\u0435 \u0432\u0430\u0436\u043d\u0430. \u0422\u044b \u0431\u044b\u0441\u0442\u0440\u0435\u0435, \u043a\u043e\u0433\u0434\u0430 \u0441\u0442\u0438\u043c\u0443\u043b \u0438 \u0440\u0435\u0430\u043a\u0446\u0438\u044f \u0441 \u043e\u0434\u043d\u043e\u0439 \u0441\u0442\u043e\u0440\u043e\u043d\u044b, \u0438 \u043c\u0435\u0434\u043b\u0435\u043d\u043d\u0435\u0435 \u043f\u0440\u0438 \u043a\u043e\u043d\u0444\u043b\u0438\u043a\u0442\u0435.",benefit:"\u0421\u043f\u043e\u0441\u043e\u0431\u043d\u043e\u0441\u0442\u044c \u0434\u0435\u0439\u0441\u0442\u0432\u043e\u0432\u0430\u0442\u044c \u043f\u043e \u043d\u0443\u0436\u043d\u043e\u043c\u0443 \u043f\u0440\u0438\u0437\u043d\u0430\u043a\u0443, \u0438\u0433\u043d\u043e\u0440\u0438\u0440\u0443\u044f \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u043e\u0435 \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0435 \u043f\u0440\u0438\u0442\u044f\u0436\u0435\u043d\u0438\u0435 \u2014 \u0447\u0438\u0441\u0442\u044b\u0439 \u0442\u0435\u0441\u0442 \u043a\u043e\u043d\u0444\u043b\u0438\u043a\u0442\u0430 \xab\u0441\u0442\u0438\u043c\u0443\u043b-\u0440\u0435\u0430\u043a\u0446\u0438\u044f\xbb \u0438 \u043a\u043e\u0433\u043d\u0438\u0442\u0438\u0432\u043d\u043e\u0433\u043e \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044f.",history:"\u041e\u043f\u0438\u0441\u0430\u043d \u0432 1960-\u0435; \u044d\u0444\u0444\u0435\u043a\u0442 \u0421\u0430\u0439\u043c\u043e\u043d\u0430 \u0441\u0442\u0430\u043b \u043a\u0440\u0430\u0435\u0443\u0433\u043e\u043b\u044c\u043d\u044b\u043c \u0432 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u044f\u0445 \u0441\u043e\u0432\u043c\u0435\u0441\u0442\u0438\u043c\u043e\u0441\u0442\u0438 \xab\u0441\u0442\u0438\u043c\u0443\u043b-\u0440\u0435\u0430\u043a\u0446\u0438\u044f\xbb \u0438 \u0442\u043e\u0433\u043e, \u043a\u0430\u043a \u043d\u0435\u0440\u0435\u043b\u0435\u0432\u0430\u043d\u0442\u043d\u043e\u0435 \u0440\u0430\u0441\u043f\u043e\u043b\u043e\u0436\u0435\u043d\u0438\u0435 \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u0438 \u0441\u043c\u0435\u0449\u0430\u0435\u0442 \u043d\u0430\u0448\u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044f.",creator:"\u0414\u0436. \u0420. \u0421\u0430\u0439\u043c\u043e\u043d \u2014 \u0435\u0433\u043e \u0440\u0430\u0431\u043e\u0442\u044b 1960-\u0445 (\u043f\u0440\u0435\u0436\u0434\u0435 \u0432\u0441\u0435\u0433\u043e Simon & Rudell, 1967) \u043e\u043f\u0440\u0435\u0434\u0435\u043b\u0438\u043b\u0438 \u044d\u0444\u0444\u0435\u043a\u0442, \u043d\u043e\u0441\u044f\u0449\u0438\u0439 \u0442\u0435\u043f\u0435\u0440\u044c \u0435\u0433\u043e \u0438\u043c\u044f.",methods:"\u0414\u0435\u0440\u0436\u0438\u0441\u044c \u043f\u0440\u0430\u0432\u0438\u043b\u0430 \u2014 \u0440\u0435\u0430\u0433\u0438\u0440\u0443\u0439 \u043d\u0430 \u0446\u0432\u0435\u0442, \u0430 \u043d\u0435 \u043d\u0430 \u0441\u0442\u043e\u0440\u043e\u043d\u0443. \u0421\u043b\u0435\u0434\u0438 \u0437\u0430 \u044d\u0444\u0444\u0435\u043a\u0442\u043e\u043c \u0421\u0430\u0439\u043c\u043e\u043d\u0430 (\u0446\u0435\u043d\u043e\u0439 \u043d\u0435\u0441\u043e\u0432\u043f\u0430\u0434\u0430\u044e\u0449\u0435\u0439 \u043f\u043e\u0437\u0438\u0446\u0438\u0438) \u0438 \u043e\u0442\u0432\u0435\u0447\u0430\u0439 \u043f\u043e \u043f\u0440\u0430\u0432\u0438\u043b\u0443, \u0434\u0430\u0436\u0435 \u043a\u043e\u0433\u0434\u0430 \u043f\u043e\u0437\u0438\u0446\u0438\u044f \u0442\u044f\u043d\u0435\u0442 \u043d\u0435 \u0442\u0443 \u0440\u0443\u043a\u0443.",duration:"\u041a\u043e\u0440\u043e\u0442\u043a\u0438\u0435 \u0441\u0435\u0441\u0441\u0438\u0438 \u043f\u043e \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u043c\u0438\u043d\u0443\u0442. \u0426\u0435\u043d\u0430 \u043a\u043e\u043d\u0444\u043b\u0438\u043a\u0442\u0430 \u043e\u0431\u044b\u0447\u043d\u043e \u043f\u0430\u0434\u0430\u0435\u0442 \u043d\u0430 \u0440\u0430\u043d\u043d\u0435\u0439 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u0435, \u043f\u043e\u0442\u043e\u043c \u0443\u0441\u0442\u0430\u043a\u0430\u043d\u0438\u0432\u0430\u0435\u0442\u0441\u044f.",research:"\u041d\u0430\u0434\u0451\u0436\u043d\u044b\u0439, \u043c\u043d\u043e\u0433\u043e\u043a\u0440\u0430\u0442\u043d\u043e \u0438\u0437\u0443\u0447\u0435\u043d\u043d\u044b\u0439 \u044d\u0444\u0444\u0435\u043a\u0442. \u041f\u0440\u0430\u043a\u0442\u0438\u043a\u0430 \u0441\u043d\u0438\u0436\u0430\u0435\u0442 \u0442\u0432\u043e\u044e \u0446\u0435\u043d\u0443 \u0421\u0430\u0439\u043c\u043e\u043d\u0430 \u0432 \u0437\u0430\u0434\u0430\u0447\u0435; \u0448\u0438\u0440\u043e\u043a\u0438\u0439 \u043f\u0435\u0440\u0435\u043d\u043e\u0441 \u043d\u0430 \u043d\u0435\u0441\u0432\u044f\u0437\u0430\u043d\u043d\u044b\u0435 \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u0438 \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044f, \u043a\u0430\u043a \u043e\u0431\u044b\u0447\u043d\u043e \u0443 \u044d\u0442\u0438\u0445 \u043f\u0430\u0440\u0430\u0434\u0438\u0433\u043c, \u0443\u043c\u0435\u0440\u0435\u043d\u043d\u044b\u0439.",rec:"\u0418\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0439, \u0447\u0442\u043e\u0431\u044b \u043e\u0442\u0440\u0430\u0431\u0430\u0442\u044b\u0432\u0430\u0442\u044c \u043e\u0442\u0432\u0435\u0442 \u043f\u043e \u043f\u0440\u0430\u0432\u0438\u043b\u0443 \u043f\u0440\u043e\u0442\u0438\u0432 \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u043e\u0439 \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0439 \u043f\u0440\u0438\u0432\u044b\u0447\u043a\u0438. \u0414\u0435\u043b\u0430\u0439 \u0441\u0442\u0430\u0432\u043a\u0443 \u043d\u0430 \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u044c; \u043f\u043e\u0431\u0435\u0434\u0430 \u2014 \u043f\u0435\u0440\u0435\u0441\u0438\u043b\u0438\u0442\u044c \u043f\u043e\u0437\u0438\u0446\u0438\u044e, \u0430 \u043d\u0435 \u0447\u0438\u0441\u0442\u0430\u044f \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c.",faq:[["\u0427\u0442\u043e \u0442\u0430\u043a\u043e\u0435 \u044d\u0444\u0444\u0435\u043a\u0442 \u0421\u0430\u0439\u043c\u043e\u043d\u0430?","\u0420\u0435\u0430\u043a\u0446\u0438\u044f \u043c\u0435\u0434\u043b\u0435\u043d\u043d\u0435\u0435, \u043a\u043e\u0433\u0434\u0430 \u0441\u0442\u0438\u043c\u0443\u043b \u043f\u043e\u044f\u0432\u043b\u044f\u0435\u0442\u0441\u044f \u0441\u043e \u0441\u0442\u043e\u0440\u043e\u043d\u044b, \u043f\u0440\u043e\u0442\u0438\u0432\u043e\u043f\u043e\u043b\u043e\u0436\u043d\u043e\u0439 \u043d\u0443\u0436\u043d\u043e\u0439 \u043a\u043b\u0430\u0432\u0438\u0448\u0435, \u0445\u043e\u0442\u044f \u043f\u043e\u0437\u0438\u0446\u0438\u044f \u043d\u0435 \u0432\u0430\u0436\u043d\u0430."],["\u0427\u0435\u043c \u043e\u0442\u043b\u0438\u0447\u0430\u0435\u0442\u0441\u044f \u043e\u0442 \u0421\u0442\u0440\u0443\u043f\u0430?","\u0423 \u0421\u0442\u0440\u0443\u043f\u0430 \u043a\u043e\u043d\u0444\u043b\u0438\u043a\u0442 \u043c\u0435\u0436\u0434\u0443 \u0437\u043d\u0430\u0447\u0435\u043d\u0438\u0435\u043c \u0441\u043b\u043e\u0432\u0430 \u0438 \u043a\u0440\u0430\u0441\u043a\u043e\u0439; \u0443 \u0421\u0430\u0439\u043c\u043e\u043d\u0430 \u2014 \u043c\u0435\u0436\u0434\u0443 \u0440\u0430\u0441\u043f\u043e\u043b\u043e\u0436\u0435\u043d\u0438\u0435\u043c \u0441\u0442\u0438\u043c\u0443\u043b\u0430 \u0438 \u0441\u0442\u043e\u0440\u043e\u043d\u043e\u0439 \u043e\u0442\u0432\u0435\u0442\u0430."],["\u0427\u0442\u043e \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442?","\u0421\u043e\u043f\u0440\u043e\u0442\u0438\u0432\u043b\u0435\u043d\u0438\u0435 \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u043e\u0439 \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0439 \u0440\u0435\u0430\u043a\u0446\u0438\u0438 \u0432 \u043f\u043e\u043b\u044c\u0437\u0443 \u043d\u0443\u0436\u043d\u043e\u0433\u043e \u043f\u043e \u043f\u0440\u0430\u0432\u0438\u043b\u0443 \u043f\u0440\u0438\u0437\u043d\u0430\u043a\u0430."]],variants:"\u0426\u0432\u0435\u0442\u043e\u0432\u044b\u0435, \u0444\u043e\u0440\u043c\u043e\u0432\u044b\u0435 \u0438\u043b\u0438 \u0437\u0432\u0443\u043a\u043e\u0432\u044b\u0435 \u0437\u0430\u0434\u0430\u0447\u0438 \u0421\u0430\u0439\u043c\u043e\u043d\u0430; \u0441\u043b\u0443\u0445\u043e\u0432\u044b\u0435 \u0432\u0435\u0440\u0441\u0438\u0438 (\u043b\u0435\u0432\u043e\u0435/\u043f\u0440\u0430\u0432\u043e\u0435 \u0443\u0445\u043e); \u043a\u043e\u043c\u0431\u0438\u043d\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u044b\u0435 \u0441\u0445\u0435\u043c\u044b, \u0441\u043c\u0435\u0448\u0438\u0432\u0430\u044e\u0449\u0438\u0435 \u0421\u0430\u0439\u043c\u043e\u043d \u0441 \u0444\u043b\u0430\u043d\u043a\u0435\u0440\u043e\u043c \u0438\u043b\u0438 \u0421\u0442\u0440\u0443\u043f\u043e\u043c."},en:{about:"A stimulus such as a colour tells you which key to press, while its position on screen is irrelevant. You are faster when stimulus and response are on the same side \u2014 and slower when they clash.",benefit:"The ability to act on a relevant feature while ignoring an automatic spatial pull \u2014 a clean test of stimulus-response conflict and cognitive control.",history:"Described in the 1960s, the Simon effect became a cornerstone of research on stimulus-response compatibility and how irrelevant location automatically biases our actions.",creator:"J. R. Simon, whose work in the 1960s (notably Simon & Rudell, 1967) defined the effect that now bears his name.",methods:"Commit to the rule \u2014 respond to the colour, not the side. Track your Simon effect (the cost of mismatched position) and keep responding by rule even when location tempts the wrong hand.",duration:"Brief sessions of a few minutes. The conflict cost usually drops over early practice and then settles.",research:"A reliable, much-studied effect. Practice reduces your own Simon cost on the task; broad transfer to unrelated control situations is, as usual for these paradigms, modest.",rec:"Use it to drill rule-based responding against an automatic spatial habit. Favour accuracy; the win is overriding location, not raw speed.",faq:[["What is the Simon effect?","Responses are slower when the stimulus appears on the opposite side to the correct response key, even though position is irrelevant."],["How is it different from Stroop?","Stroop conflict is between word meaning and ink colour; Simon conflict is between stimulus location and response side."],["What does it train?","Resisting an automatic spatial response in favour of the rule-relevant feature."]],variants:"Colour, shape or sound Simon tasks; auditory (left/right ear) versions; and combined designs mixing Simon with flanker or Stroop."},es:{about:"Un est\xedmulo, como un color, te indica qu\xe9 tecla pulsar, mientras que su posici\xf3n en la pantalla es irrelevante. Eres m\xe1s r\xe1pido cuando el est\xedmulo y la respuesta est\xe1n en el mismo lado, y m\xe1s lento cuando chocan.",benefit:"La capacidad de actuar seg\xfan una caracter\xedstica relevante mientras ignoras un tir\xf3n espacial autom\xe1tico: una prueba limpia del conflicto est\xedmulo-respuesta y del control cognitivo.",history:"Descrito en los a\xf1os sesenta, el efecto Simon se convirti\xf3 en una piedra angular de la investigaci\xf3n sobre la compatibilidad est\xedmulo-respuesta y sobre c\xf3mo la posici\xf3n irrelevante sesga de forma autom\xe1tica nuestras acciones.",creator:"J. R. Simon, cuyo trabajo en los a\xf1os sesenta (en particular Simon & Rudell, 1967) defini\xf3 el efecto que hoy lleva su nombre.",methods:"Comprom\xe9tete con la regla: responde al color, no al lado. Sigue tu efecto Simon (el coste de la posici\xf3n discordante) y mant\xe9n la respuesta seg\xfan la regla incluso cuando la ubicaci\xf3n tiente a la mano equivocada.",duration:"Sesiones breves de unos minutos. El coste del conflicto suele bajar durante la pr\xe1ctica inicial y luego se estabiliza.",research:"Un efecto fiable y muy estudiado. La pr\xe1ctica reduce tu propio coste Simon en la tarea; la transferencia amplia a situaciones de control no relacionadas es, como suele pasar con estos paradigmas, modesta.",rec:"\xdasalo para entrenar la respuesta basada en reglas frente a un h\xe1bito espacial autom\xe1tico. Prioriza la exactitud; el logro est\xe1 en imponerse a la ubicaci\xf3n, no en la velocidad bruta.",faq:[["\xbfQu\xe9 es el efecto Simon?","Las respuestas son m\xe1s lentas cuando el est\xedmulo aparece en el lado opuesto a la tecla de respuesta correcta, aunque la posici\xf3n sea irrelevante."],["\xbfEn qu\xe9 se diferencia de Stroop?","El conflicto Stroop es entre el significado de la palabra y el color de la tinta; el conflicto Simon es entre la ubicaci\xf3n del est\xedmulo y el lado de la respuesta."],["\xbfQu\xe9 entrena?","A resistir una respuesta espacial autom\xe1tica en favor de la caracter\xedstica relevante seg\xfan la regla."]],variants:"Tareas Simon de color, forma o sonido; versiones auditivas (o\xeddo izquierdo/derecho); y dise\xf1os combinados que mezclan Simon con la tarea de flancos o con Stroop."},de:{about:"Ein Reiz wie etwa eine Farbe sagt dir, welche Taste du dr\xfccken sollst, w\xe4hrend seine Position auf dem Bildschirm irrelevant ist. Du bist schneller, wenn Reiz und Antwort auf derselben Seite liegen \u2013 und langsamer, wenn sie sich widersprechen.",benefit:"Die F\xe4higkeit, nach einem relevanten Merkmal zu handeln, w\xe4hrend du einen automatischen r\xe4umlichen Sog ignorierst \u2013 ein sauberer Test von Reiz-Reaktions-Konflikt und kognitiver Kontrolle.",history:"In den 1960er-Jahren beschrieben, wurde der Simon-Effekt zu einem Eckpfeiler der Forschung \xfcber die Reiz-Reaktions-Kompatibilit\xe4t und dar\xfcber, wie eine irrelevante Position unsere Handlungen automatisch verzerrt.",creator:"J. R. Simon, dessen Arbeit in den 1960er-Jahren (insbesondere Simon & Rudell, 1967) den Effekt definierte, der heute seinen Namen tr\xe4gt.",methods:"Lege dich auf die Regel fest \u2013 reagiere auf die Farbe, nicht auf die Seite. Verfolge deinen Simon-Effekt (die Kosten der nicht \xfcbereinstimmenden Position) und antworte weiter nach der Regel, auch wenn die Position die falsche Hand verlockt.",duration:"Kurze Sitzungen von wenigen Minuten. Die Konfliktkosten sinken meist \xfcber die fr\xfche \xdcbung und pendeln sich dann ein.",research:"Ein zuverl\xe4ssiger, viel untersuchter Effekt. \xdcbung verringert deine eigenen Simon-Kosten in der Aufgabe; ein breiter Transfer auf unverwandte Kontrollsituationen ist, wie bei diesen Paradigmen \xfcblich, m\xe4\xdfig.",rec:"Nutze ihn, um regelbasiertes Antworten gegen eine automatische r\xe4umliche Gewohnheit zu \xfcben. Bevorzuge Genauigkeit; der Gewinn liegt im \xdcberschreiben der Position, nicht in roher Geschwindigkeit.",faq:[["Was ist der Simon-Effekt?","Reaktionen sind langsamer, wenn der Reiz auf der entgegengesetzten Seite zur richtigen Antworttaste erscheint, obwohl die Position irrelevant ist."],["Wie unterscheidet er sich von Stroop?","Der Stroop-Konflikt besteht zwischen Wortbedeutung und Druckfarbe; der Simon-Konflikt besteht zwischen der Position des Reizes und der Antwortseite."],["Was trainiert er?","Einer automatischen r\xe4umlichen Reaktion zu widerstehen zugunsten des regelrelevanten Merkmals."]],variants:"Simon-Aufgaben mit Farbe, Form oder Ton; auditive Versionen (linkes/rechtes Ohr); und kombinierte Designs, die Simon mit Flanker oder Stroop mischen."},pt:{about:"Um est\xedmulo, como uma cor, indica qual tecla pressionar, enquanto a sua posi\xe7\xe3o no ecr\xe3 \xe9 irrelevante. Voc\xea \xe9 mais r\xe1pido quando o est\xedmulo e a resposta est\xe3o do mesmo lado \u2014 e mais lento quando eles se contradizem.",benefit:"A capacidade de agir sobre uma caracter\xedstica relevante ignorando um pux\xe3o espacial autom\xe1tico \u2014 um teste limpo do conflito est\xedmulo-resposta e do controle cognitivo.",history:"Descrito nos anos 1960, o efeito Simon tornou-se uma pedra angular da investiga\xe7\xe3o sobre a compatibilidade est\xedmulo-resposta e sobre como a localiza\xe7\xe3o irrelevante enviesa automaticamente as nossas a\xe7\xf5es.",creator:"J. R. Simon, cujo trabalho nos anos 1960 (em especial Simon & Rudell, 1967) definiu o efeito que hoje leva o seu nome.",methods:"Comprometa-se com a regra \u2014 responda \xe0 cor, n\xe3o ao lado. Acompanhe o seu efeito Simon (o custo da posi\xe7\xe3o incompat\xedvel) e continue a responder pela regra mesmo quando a localiza\xe7\xe3o tenta puxar a m\xe3o errada.",duration:"Sess\xf5es breves de alguns minutos. O custo do conflito costuma cair logo na fase inicial de pr\xe1tica e depois estabiliza.",research:"Um efeito fi\xe1vel e muito estudado. A pr\xe1tica reduz o seu pr\xf3prio custo de Simon na tarefa; a transfer\xeancia ampla para situa\xe7\xf5es de controle n\xe3o relacionadas \xe9, como de costume nesses paradigmas, modesta.",rec:"Use-o para treinar a resposta baseada em regra contra um h\xe1bito espacial autom\xe1tico. Privilegie a precis\xe3o; a conquista \xe9 vencer a localiza\xe7\xe3o, n\xe3o a velocidade bruta.",faq:[["O que \xe9 o efeito Simon?","As respostas s\xe3o mais lentas quando o est\xedmulo aparece no lado oposto ao da tecla de resposta correta, ainda que a posi\xe7\xe3o seja irrelevante."],["Em que difere do Stroop?","O conflito de Stroop \xe9 entre o significado da palavra e a cor da tinta; o conflito de Simon \xe9 entre a localiza\xe7\xe3o do est\xedmulo e o lado da resposta."],["O que ele treina?","Resistir a uma resposta espacial autom\xe1tica em favor da caracter\xedstica relevante para a regra."]],variants:"Tarefas de Simon com cor, forma ou som; vers\xf5es auditivas (ouvido esquerdo/direito); e desenhos combinados que misturam o Simon com o flanco ou com o Stroop."},hi:{about:"\u0915\u094b\u0908 \u0909\u0926\u094d\u0926\u0940\u092a\u0928, \u091c\u0948\u0938\u0947 \u090f\u0915 \u0930\u0902\u0917, \u0906\u092a\u0915\u094b \u092c\u0924\u093e\u0924\u093e \u0939\u0948 \u0915\u093f \u0915\u094c\u0928-\u0938\u0940 \u0915\u0941\u0902\u091c\u0940 \u0926\u092c\u093e\u0928\u0940 \u0939\u0948, \u091c\u092c\u0915\u093f \u0938\u094d\u0915\u094d\u0930\u0940\u0928 \u092a\u0930 \u0909\u0938\u0915\u0940 \u091c\u0917\u0939 \u092c\u0947\u092e\u0924\u0932\u092c \u0939\u0948\u0964 \u091c\u092c \u0909\u0926\u094d\u0926\u0940\u092a\u0928 \u0914\u0930 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u090f\u0915 \u0939\u0940 \u0924\u0930\u092b\u093c \u0939\u094b\u0902 \u0924\u092c \u0906\u092a \u0924\u0947\u091c\u093c \u0939\u094b\u0924\u0947 \u0939\u0948\u0902 \u2014 \u0914\u0930 \u091c\u092c \u0935\u0947 \u091f\u0915\u0930\u093e\u090f\u0901 \u0924\u092c \u0927\u0940\u092e\u0947\u0964",benefit:"\u0915\u093f\u0938\u0940 \u092a\u094d\u0930\u093e\u0938\u0902\u0917\u093f\u0915 \u0935\u093f\u0936\u0947\u0937\u0924\u093e \u092a\u0930 \u0905\u092e\u0932 \u0915\u0930\u0924\u0947 \u0939\u0941\u090f \u090f\u0915 \u0938\u094d\u0935\u0924\u0903-\u0938\u094d\u092b\u0942\u0930\u094d\u0924 \u0938\u094d\u0925\u093e\u0928\u093f\u0915 \u0916\u093f\u0902\u091a\u093e\u0935 \u0915\u094b \u0905\u0928\u0926\u0947\u0916\u093e \u0915\u0930\u0928\u0947 \u0915\u0940 \u0915\u094d\u0937\u092e\u0924\u093e \u2014 \u0909\u0926\u094d\u0926\u0940\u092a\u0928-\u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u091f\u0915\u0930\u093e\u0935 \u0914\u0930 \u0938\u0902\u091c\u094d\u091e\u093e\u0928\u093e\u0924\u094d\u092e\u0915 \u0928\u093f\u092f\u0902\u0924\u094d\u0930\u0923 \u0915\u0940 \u090f\u0915 \u0938\u093e\u092b\u093c-\u0938\u0941\u0925\u0930\u0940 \u092a\u0930\u0916\u0964",history:"1960 \u0915\u0947 \u0926\u0936\u0915 \u092e\u0947\u0902 \u0935\u0930\u094d\u0923\u093f\u0924, Simon \u092a\u094d\u0930\u092d\u093e\u0935 \u0909\u0926\u094d\u0926\u0940\u092a\u0928-\u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0938\u0902\u0917\u0924\u093f \u092a\u0930 \u2014 \u0914\u0930 \u0907\u0938 \u092a\u0930 \u0915\u093f \u092c\u0947\u092e\u0924\u0932\u092c \u091c\u0917\u0939 \u0915\u0948\u0938\u0947 \u0905\u092a\u0928\u0947-\u0906\u092a \u0939\u092e\u093e\u0930\u0947 \u0915\u093e\u092e\u094b\u0902 \u0915\u094b \u091d\u0941\u0915\u093e \u0926\u0947\u0924\u0940 \u0939\u0948 \u2014 \u0939\u094b\u0928\u0947 \u0935\u093e\u0932\u0947 \u0905\u0928\u0941\u0938\u0902\u0927\u093e\u0928 \u0915\u0940 \u0906\u0927\u093e\u0930\u0936\u093f\u0932\u093e \u092c\u0928 \u0917\u092f\u093e\u0964",creator:"J. R. Simon, \u091c\u093f\u0928\u0915\u0947 1960 \u0915\u0947 \u0926\u0936\u0915 \u0915\u0947 \u0915\u093e\u092e (\u0916\u093e\u0938\u0915\u0930 Simon & Rudell, 1967) \u0928\u0947 \u0909\u0938 \u092a\u094d\u0930\u092d\u093e\u0935 \u0915\u094b \u092a\u0930\u093f\u092d\u093e\u0937\u093f\u0924 \u0915\u093f\u092f\u093e \u091c\u094b \u0905\u092c \u0909\u0928\u094d\u0939\u0940\u0902 \u0915\u0947 \u0928\u093e\u092e \u0938\u0947 \u091c\u093e\u0928\u093e \u091c\u093e\u0924\u093e \u0939\u0948\u0964",methods:"\u0928\u093f\u092f\u092e \u092a\u0930 \u0905\u0921\u093c\u0947 \u0930\u0939\u0947\u0902 \u2014 \u0930\u0902\u0917 \u092a\u0930 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0926\u0947\u0902, \u0909\u0938 \u0924\u0930\u092b\u093c \u092a\u0930 \u0928\u0939\u0940\u0902\u0964 \u0905\u092a\u0928\u0947 Simon \u092a\u094d\u0930\u092d\u093e\u0935 (\u092c\u0947\u092e\u0947\u0932 \u091c\u0917\u0939 \u0915\u0940 \u0915\u0940\u092e\u0924) \u092a\u0930 \u0928\u091c\u093c\u0930 \u0930\u0916\u0947\u0902, \u0914\u0930 \u0924\u092c \u092d\u0940 \u0928\u093f\u092f\u092e \u0915\u0947 \u092e\u0941\u0924\u093e\u092c\u093f\u0915\u093c \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0926\u0947\u0924\u0947 \u0930\u0939\u0947\u0902 \u091c\u092c \u091c\u0917\u0939 \u0917\u0932\u0924 \u0939\u093e\u0925 \u0915\u0940 \u0913\u0930 \u0932\u0932\u091a\u093e\u090f\u0964",duration:"\u0915\u0941\u091b \u092e\u093f\u0928\u091f\u094b\u0902 \u0915\u0947 \u091b\u094b\u091f\u0947 \u0938\u0924\u094d\u0930\u0964 \u091f\u0915\u0930\u093e\u0935 \u0915\u0940 \u0915\u0940\u092e\u0924 \u0906\u092e\u0924\u094c\u0930 \u092a\u0930 \u0936\u0941\u0930\u0941\u0906\u0924\u0940 \u0905\u092d\u094d\u092f\u093e\u0938 \u092e\u0947\u0902 \u0918\u091f\u0924\u0940 \u0939\u0948 \u0914\u0930 \u092b\u093f\u0930 \u090f\u0915 \u091c\u0917\u0939 \u091c\u092e \u091c\u093e\u0924\u0940 \u0939\u0948\u0964",research:"\u090f\u0915 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926, \u0916\u093c\u0942\u092c \u0905\u0927\u094d\u092f\u092f\u0928 \u0915\u093f\u092f\u093e \u0917\u092f\u093e \u092a\u094d\u0930\u092d\u093e\u0935\u0964 \u0905\u092d\u094d\u092f\u093e\u0938 \u0907\u0938 \u0915\u093e\u0930\u094d\u092f \u092a\u0930 \u0906\u092a\u0915\u0940 \u0905\u092a\u0928\u0940 Simon \u0915\u0940\u092e\u0924 \u0918\u091f\u093e\u0924\u093e \u0939\u0948; \u0905\u0938\u0902\u092c\u0902\u0927\u093f\u0924 \u0928\u093f\u092f\u0902\u0924\u094d\u0930\u0923 \u0938\u094d\u0925\u093f\u0924\u093f\u092f\u094b\u0902 \u0924\u0915 \u0935\u094d\u092f\u093e\u092a\u0915 \u0938\u094d\u0925\u093e\u0928\u093e\u0902\u0924\u0930\u0923, \u0907\u0928 \u092a\u094d\u0930\u0924\u093f\u092e\u093e\u0928\u094b\u0902 \u0915\u0947 \u0932\u093f\u090f \u0939\u092e\u0947\u0936\u093e \u0915\u0940 \u0924\u0930\u0939, \u092e\u093e\u092e\u0942\u0932\u0940 \u0939\u0940 \u0930\u0939\u0924\u093e \u0939\u0948\u0964",rec:"\u0907\u0938\u0915\u093e \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u090f\u0915 \u0938\u094d\u0935\u0924\u0903-\u0938\u094d\u092b\u0942\u0930\u094d\u0924 \u0938\u094d\u0925\u093e\u0928\u093f\u0915 \u0906\u0926\u0924 \u0915\u0947 \u0916\u093c\u093f\u0932\u093e\u092b\u093c \u0928\u093f\u092f\u092e-\u0906\u0927\u093e\u0930\u093f\u0924 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0930\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0915\u0930\u0947\u0902\u0964 \u0938\u091f\u0940\u0915\u0924\u093e \u0915\u094b \u0924\u0930\u091c\u0940\u0939 \u0926\u0947\u0902; \u091c\u0940\u0924 \u091c\u0917\u0939 \u0915\u094b \u092e\u093e\u0924 \u0926\u0947\u0928\u0947 \u092e\u0947\u0902 \u0939\u0948, \u0915\u091a\u094d\u091a\u0940 \u0917\u0924\u093f \u092e\u0947\u0902 \u0928\u0939\u0940\u0902\u0964",faq:[["Simon \u092a\u094d\u0930\u092d\u093e\u0935 \u0915\u094d\u092f\u093e \u0939\u0948?","\u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e\u090f\u0901 \u0924\u092c \u0927\u0940\u092e\u0940 \u0939\u094b\u0924\u0940 \u0939\u0948\u0902 \u091c\u092c \u0909\u0926\u094d\u0926\u0940\u092a\u0928 \u0938\u0939\u0940 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0915\u0941\u0902\u091c\u0940 \u0915\u0940 \u0909\u0932\u091f\u0940 \u0924\u0930\u092b\u093c \u092a\u094d\u0930\u0915\u091f \u0939\u094b\u0924\u093e \u0939\u0948, \u0939\u093e\u0932\u093e\u0901\u0915\u093f \u091c\u0917\u0939 \u092c\u0947\u092e\u0924\u0932\u092c \u0939\u094b\u0924\u0940 \u0939\u0948\u0964"],["\u092f\u0939 Stroop \u0938\u0947 \u0915\u0948\u0938\u0947 \u0905\u0932\u0917 \u0939\u0948?","Stroop \u0915\u093e \u091f\u0915\u0930\u093e\u0935 \u0936\u092c\u094d\u0926 \u0915\u0947 \u0905\u0930\u094d\u0925 \u0914\u0930 \u0938\u094d\u092f\u093e\u0939\u0940 \u0915\u0947 \u0930\u0902\u0917 \u0915\u0947 \u092c\u0940\u091a \u0939\u094b\u0924\u093e \u0939\u0948; Simon \u0915\u093e \u091f\u0915\u0930\u093e\u0935 \u0909\u0926\u094d\u0926\u0940\u092a\u0928 \u0915\u0940 \u091c\u0917\u0939 \u0914\u0930 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0915\u0940 \u0924\u0930\u092b\u093c \u0915\u0947 \u092c\u0940\u091a \u0939\u094b\u0924\u093e \u0939\u0948\u0964"],["\u092f\u0939 \u0915\u094d\u092f\u093e \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u093f\u0924 \u0915\u0930\u0924\u093e \u0939\u0948?","\u090f\u0915 \u0938\u094d\u0935\u0924\u0903-\u0938\u094d\u092b\u0942\u0930\u094d\u0924 \u0938\u094d\u0925\u093e\u0928\u093f\u0915 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0915\u093e \u0935\u093f\u0930\u094b\u0927 \u0915\u0930\u0915\u0947 \u0928\u093f\u092f\u092e-\u092a\u094d\u0930\u093e\u0938\u0902\u0917\u093f\u0915 \u0935\u093f\u0936\u0947\u0937\u0924\u093e \u0915\u094b \u0924\u0930\u091c\u0940\u0939 \u0926\u0947\u0928\u093e\u0964"]],variants:"\u0930\u0902\u0917, \u0906\u0915\u0943\u0924\u093f \u092f\u093e \u0927\u094d\u0935\u0928\u093f \u0935\u093e\u0932\u0947 Simon \u0915\u093e\u0930\u094d\u092f; \u0936\u094d\u0930\u0935\u0923 (\u092c\u093e\u092f\u093e\u0901/\u0926\u093e\u092f\u093e\u0901 \u0915\u093e\u0928) \u0938\u0902\u0938\u094d\u0915\u0930\u0923; \u0914\u0930 \u092e\u093f\u0936\u094d\u0930\u093f\u0924 \u0921\u093f\u091c\u093c\u093e\u0907\u0928 \u091c\u094b Simon \u0915\u094b flanker \u092f\u093e Stroop \u0915\u0947 \u0938\u093e\u0925 \u092e\u093f\u0932\u093e \u0926\u0947\u0924\u0947 \u0939\u0948\u0902\u0964"},zh:{about:"\u67d0\u4e2a\u523a\u6fc0\uff08\u6bd4\u5982\u989c\u8272\uff09\u544a\u8bc9\u4f60\u8be5\u6309\u54ea\u4e2a\u952e\uff0c\u800c\u5b83\u5728\u5c4f\u5e55\u4e0a\u7684\u4f4d\u7f6e\u5219\u65e0\u5173\u7d27\u8981\u3002\u5f53\u523a\u6fc0\u548c\u53cd\u5e94\u5728\u540c\u4e00\u4fa7\u65f6\u4f60\u66f4\u5feb\u2014\u2014\u5f53\u4e8c\u8005\u51b2\u7a81\u65f6\u5219\u66f4\u6162\u3002",benefit:"\u4f9d\u636e\u76f8\u5173\u7279\u5f81\u884c\u52a8\u3001\u540c\u65f6\u65e0\u89c6\u4e00\u79cd\u81ea\u52a8\u7684\u7a7a\u95f4\u7275\u5f15\u7684\u80fd\u529b\u2014\u2014\u8fd9\u662f\u5bf9\u523a\u6fc0-\u53cd\u5e94\u51b2\u7a81\u548c\u8ba4\u77e5\u63a7\u5236\u7684\u4e00\u6b21\u5e72\u51c0\u7684\u68c0\u9a8c\u3002",history:"\u897f\u8499\u6548\u5e94\uff08Simon effect\uff09\u4e8e 1960 \u5e74\u4ee3\u88ab\u63cf\u8ff0\uff0c\u540e\u6765\u6210\u4e3a\u7814\u7a76\u523a\u6fc0-\u53cd\u5e94\u76f8\u5bb9\u6027\u3001\u4ee5\u53ca\u65e0\u5173\u4f4d\u7f6e\u5982\u4f55\u81ea\u52a8\u504f\u7f6e\u6211\u4eec\u884c\u52a8\u7684\u4e00\u5757\u57fa\u77f3\u3002",creator:"J. R. Simon\uff0c\u4ed6\u5728 1960 \u5e74\u4ee3\u7684\u5de5\u4f5c\uff08\u5c24\u5176\u662f Simon & Rudell, 1967\uff09\u5b9a\u4e49\u4e86\u5982\u4eca\u4ee5\u4ed6\u547d\u540d\u7684\u8fd9\u4e00\u6548\u5e94\u3002",methods:"\u7b03\u5b9a\u5730\u5b88\u4f4f\u89c4\u5219\u2014\u2014\u5bf9\u989c\u8272\u53cd\u5e94\uff0c\u800c\u4e0d\u662f\u5bf9\u90a3\u4e00\u4fa7\u53cd\u5e94\u3002\u8ffd\u8e2a\u4f60\u81ea\u5df1\u7684\u897f\u8499\u6548\u5e94\uff08\u4f4d\u7f6e\u4e0d\u4e00\u81f4\u5e26\u6765\u7684\u4ee3\u4ef7\uff09\uff0c\u5373\u4f7f\u4f4d\u7f6e\u5728\u5f15\u8bf1\u9519\u8bef\u7684\u90a3\u53ea\u624b\uff0c\u4e5f\u8981\u575a\u6301\u6309\u89c4\u5219\u5e94\u7b54\u3002",duration:"\u51e0\u5206\u949f\u7684\u77ed\u65f6\u6bb5\u3002\u51b2\u7a81\u4ee3\u4ef7\u901a\u5e38\u5728\u65e9\u671f\u7ec3\u4e60\u4e2d\u4e0b\u964d\uff0c\u968f\u540e\u8d8b\u4e8e\u7a33\u5b9a\u3002",research:"\u8fd9\u662f\u4e00\u4e2a\u53ef\u9760\u3001\u88ab\u5927\u91cf\u7814\u7a76\u7684\u6548\u5e94\u3002\u7ec3\u4e60\u4f1a\u964d\u4f4e\u4f60\u81ea\u5df1\u5728\u8be5\u4efb\u52a1\u4e0a\u7684\u897f\u8499\u4ee3\u4ef7\uff1b\u81f3\u4e8e\u5e7f\u6cdb\u8fc1\u79fb\u5230\u65e0\u5173\u7684\u63a7\u5236\u60c5\u5883\uff0c\u5219\u4e00\u5982\u8fd9\u7c7b\u8303\u5f0f\u7684\u60ef\u4f8b\uff0c\u76f8\u5f53\u6709\u9650\u3002",rec:"\u7528\u5b83\u6765\u64cd\u7ec3\u300c\u6309\u89c4\u5219\u5e94\u7b54\u300d\u53bb\u5bf9\u6297\u4e00\u79cd\u81ea\u52a8\u7684\u7a7a\u95f4\u4e60\u60ef\u3002\u504f\u5411\u51c6\u786e\uff1b\u8981\u8d62\u7684\u662f\u300c\u538b\u8fc7\u4f4d\u7f6e\u300d\uff0c\u800c\u4e0d\u662f\u5355\u7eaf\u7684\u901f\u5ea6\u3002",faq:[["\u4ec0\u4e48\u662f\u897f\u8499\u6548\u5e94\uff1f","\u5f53\u523a\u6fc0\u51fa\u73b0\u5728\u4e0e\u6b63\u786e\u53cd\u5e94\u952e\u76f8\u53cd\u7684\u4e00\u4fa7\u65f6\uff0c\u53cd\u5e94\u4f1a\u66f4\u6162\uff0c\u5373\u4fbf\u4f4d\u7f6e\u672c\u8eab\u65e0\u5173\u7d27\u8981\u3002"],["\u5b83\u548c\u65af\u7279\u9c81\u666e\uff08Stroop\uff09\u6709\u4ec0\u4e48\u4e0d\u540c\uff1f","\u65af\u7279\u9c81\u666e\u51b2\u7a81\u53d1\u751f\u5728\u8bcd\u4e49\u548c\u58a8\u6c34\u989c\u8272\u4e4b\u95f4\uff1b\u897f\u8499\u51b2\u7a81\u53d1\u751f\u5728\u523a\u6fc0\u4f4d\u7f6e\u548c\u53cd\u5e94\u4fa7\u4e4b\u95f4\u3002"],["\u5b83\u8bad\u7ec3\u4ec0\u4e48\uff1f","\u62b5\u6297\u4e00\u79cd\u81ea\u52a8\u7684\u7a7a\u95f4\u53cd\u5e94\uff0c\u8f6c\u800c\u4f9d\u636e\u4e0e\u89c4\u5219\u76f8\u5173\u7684\u7279\u5f81\u884c\u52a8\u3002"]],variants:"\u989c\u8272\u3001\u5f62\u72b6\u6216\u58f0\u97f3\u7684\u897f\u8499\u4efb\u52a1\uff1b\u542c\u89c9\uff08\u5de6/\u53f3\u8033\uff09\u7248\u672c\uff1b\u4ee5\u53ca\u628a\u897f\u8499\u4e0e\u5939\u6270\u4efb\u52a1\u6216\u65af\u7279\u9c81\u666e\u6df7\u5408\u5728\u4e00\u8d77\u7684\u7ec4\u5408\u8bbe\u8ba1\u3002"}},span:{ru:{about:"\u0412 \u0438\u0433\u0440\u0435 Span: Sequence Memory \u043d\u0430 \u044d\u043a\u0440\u0430\u043d\u0435 \u043e\u0434\u043d\u0430 \u0437\u0430 \u0434\u0440\u0443\u0433\u043e\u0439 \u0437\u0430\u0433\u043e\u0440\u0430\u044e\u0442\u0441\u044f \u044f\u0447\u0435\u0439\u043a\u0438, \u0438 \u0432\u0430\u0448\u0430 \u0437\u0430\u0434\u0430\u0447\u0430 \u2014 \u043f\u043e\u0432\u0442\u043e\u0440\u0438\u0442\u044c \u044d\u0442\u0443 \u043f\u043e\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c \u0432 \u0442\u043e\u0447\u043d\u043e \u0442\u043e\u043c \u0436\u0435 \u043f\u043e\u0440\u044f\u0434\u043a\u0435. \u041a\u0430\u0436\u0434\u044b\u0439 \u0440\u0430\u0437, \u043a\u043e\u0433\u0434\u0430 \u0432\u044b \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0438\u0442\u0435 \u0435\u0451 \u0431\u0435\u0437 \u043e\u0448\u0438\u0431\u043e\u043a, \u0446\u0435\u043f\u043e\u0447\u043a\u0430 \u0443\u0434\u043b\u0438\u043d\u044f\u0435\u0442\u0441\u044f \u043d\u0430 \u043e\u0434\u0438\u043d \u0448\u0430\u0433, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u0438\u0433\u0440\u0430 \u0432\u0441\u0451 \u0432\u0440\u0435\u043c\u044f \u043f\u043e\u0434\u0432\u043e\u0434\u0438\u0442 \u0432\u0430\u0441 \u043a \u043f\u0440\u0435\u0434\u0435\u043b\u0443 \u0442\u043e\u0433\u043e, \u0447\u0442\u043e \u0432\u044b \u0441\u043f\u043e\u0441\u043e\u0431\u043d\u044b \u0443\u0434\u0435\u0440\u0436\u0430\u0442\u044c.",benefit:"\u0418\u0433\u0440\u0430 \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u043a\u0440\u0430\u0442\u043a\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u0443\u044e \u0438 \u0440\u0430\u0431\u043e\u0447\u0443\u044e \u043f\u0430\u043c\u044f\u0442\u044c \u043d\u0430 \u0443\u043f\u043e\u0440\u044f\u0434\u043e\u0447\u0435\u043d\u043d\u0443\u044e \u0438\u043d\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u044e, \u0430 \u0437\u0430\u043e\u0434\u043d\u043e \u0441\u043e\u0431\u0440\u0430\u043d\u043d\u043e\u0435 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435: \u043a\u0430\u0436\u0434\u044b\u0439 \u044d\u043b\u0435\u043c\u0435\u043d\u0442 \u043d\u0443\u0436\u043d\u043e \u0437\u0430\u0444\u0438\u043a\u0441\u0438\u0440\u043e\u0432\u0430\u0442\u044c, \u043d\u0435 \u043e\u0442\u0432\u043b\u0435\u043a\u0430\u044f\u0441\u044c. \u041f\u0440\u043e\u0449\u0435 \u0433\u043e\u0432\u043e\u0440\u044f, \u043e\u043d\u0430 \u0440\u0430\u0441\u0448\u0438\u0440\u044f\u0435\u0442 \u043e\u0431\u044a\u0451\u043c \u0442\u043e\u0433\u043e, \u0447\u0442\u043e \u0432\u044b \u0434\u0435\u0440\u0436\u0438\u0442\u0435 \u0432 \u0433\u043e\u043b\u043e\u0432\u0435 \u043e\u0434\u043d\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u043e \u0438 \u0432 \u043f\u0440\u0430\u0432\u0438\u043b\u044c\u043d\u043e\u043c \u043f\u043e\u0440\u044f\u0434\u043a\u0435.",history:"\u0418\u0433\u0440\u0430 \u0432\u044b\u0440\u043e\u0441\u043b\u0430 \u0438\u0437 \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u0438 \u0438\u0437\u043c\u0435\u0440\u0435\u043d\u0438\u044f \u043e\u0431\u044a\u0451\u043c\u0430 \u043f\u0430\u043c\u044f\u0442\u0438, \u043a\u043e\u0442\u043e\u0440\u0430\u044f \u0437\u0430\u0440\u043e\u0434\u0438\u043b\u0430\u0441\u044c \u0432 \u044d\u043a\u0441\u043f\u0435\u0440\u0438\u043c\u0435\u043d\u0442\u0430\u043b\u044c\u043d\u043e\u0439 \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u0438 \u0432 \u043a\u043e\u043d\u0446\u0435 XIX \u0432\u0435\u043a\u0430, \u043a\u043e\u0433\u0434\u0430 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u0438 \u043d\u0430\u0447\u0430\u043b\u0438 \u0432\u044b\u044f\u0441\u043d\u044f\u0442\u044c, \u043d\u0430\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0434\u043b\u0438\u043d\u043d\u0443\u044e \u0446\u0435\u043f\u043e\u0447\u043a\u0443 \u0447\u0435\u043b\u043e\u0432\u0435\u043a \u0441\u043f\u043e\u0441\u043e\u0431\u0435\u043d \u043f\u043e\u0432\u0442\u043e\u0440\u0438\u0442\u044c. \u041f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0439 \u0432\u0430\u0440\u0438\u0430\u043d\u0442 \u0441 \u0437\u0430\u0433\u043e\u0440\u0430\u044e\u0449\u0438\u043c\u0438\u0441\u044f \u044f\u0447\u0435\u0439\u043a\u0430\u043c\u0438 \u0441\u0442\u0430\u043b \u0448\u0438\u0440\u043e\u043a\u043e \u0438\u0437\u0432\u0435\u0441\u0442\u0435\u043d \u0431\u043b\u0430\u0433\u043e\u0434\u0430\u0440\u044f \u043e\u043d\u043b\u0430\u0439\u043d-\u0442\u0435\u0441\u0442\u0430\u043c \u0432 2010-\u0435 \u0433\u043e\u0434\u044b \u0438 \u043f\u0435\u0440\u0435\u043a\u043b\u0438\u043a\u0430\u0435\u0442\u0441\u044f \u0441\u043e \u0441\u0442\u0430\u0440\u044b\u043c\u0438 \u044d\u043b\u0435\u043a\u0442\u0440\u043e\u043d\u043d\u044b\u043c\u0438 \u0438\u0433\u0440\u0443\u0448\u043a\u0430\u043c\u0438, \u0433\u0434\u0435 \u043d\u0443\u0436\u043d\u043e \u043f\u043e\u0432\u0442\u043e\u0440\u044f\u0442\u044c \u0432\u0441\u0451 \u0431\u043e\u043b\u0435\u0435 \u0434\u043b\u0438\u043d\u043d\u0443\u044e \u0447\u0435\u0440\u0435\u0434\u0443 \u043e\u0433\u043e\u043d\u044c\u043a\u043e\u0432 \u0438 \u0437\u0432\u0443\u043a\u043e\u0432.",creator:"\u0423 \u044d\u0442\u043e\u0439 \u0438\u0433\u0440\u044b \u0432 \u0435\u0451 \u043d\u044b\u043d\u0435\u0448\u043d\u0435\u043c \u0432\u0438\u0434\u0435 \u043d\u0435\u0442 \u0435\u0434\u0438\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0433\u043e \u0430\u0432\u0442\u043e\u0440\u0430. \u0411\u0430\u0437\u043e\u0432\u043e\u0435 \u0437\u0430\u0434\u0430\u043d\u0438\u0435 \u043d\u0430 \u043d\u0435\u043c\u0435\u0434\u043b\u0435\u043d\u043d\u043e\u0435 \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u0435\u0434\u0435\u043d\u0438\u0435 \u043f\u043e \u043f\u043e\u0440\u044f\u0434\u043a\u0443 \u043e\u0431\u044b\u0447\u043d\u043e \u0441\u0432\u044f\u0437\u044b\u0432\u0430\u044e\u0442 \u0441 \u0414\u0436\u043e\u0437\u0435\u0444\u043e\u043c \u0414\u0436\u0435\u0439\u043a\u043e\u0431\u0441\u043e\u043c, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u0438\u0437\u043c\u0435\u0440\u0438\u043b \u043e\u0431\u044a\u0451\u043c \u043f\u0430\u043c\u044f\u0442\u0438 \u043d\u0430 \u0446\u0438\u0444\u0440\u044b \u0432 1887 \u0433\u043e\u0434\u0443; \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u043e-\u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0439 \u0432\u0430\u0440\u0438\u0430\u043d\u0442 \u0432\u043e\u0441\u0445\u043e\u0434\u0438\u0442 \u043a \u0442\u0435\u0441\u0442\u0443 \u043f\u043e\u0441\u0442\u0443\u043a\u0438\u0432\u0430\u043d\u0438\u044f \u043f\u043e \u043a\u0443\u0431\u0438\u043a\u0430\u043c \u0424\u0438\u043b\u0438\u043f\u0430 \u041a\u043e\u0440\u0441\u0438 (1972). \u041f\u0440\u0438\u0432\u044b\u0447\u043d\u0443\u044e \u0432\u0435\u0440\u0441\u0438\u044e \u0441 \u0437\u0430\u0433\u043e\u0440\u0430\u044e\u0449\u0438\u043c\u0438\u0441\u044f \u043f\u043b\u0438\u0442\u043a\u0430\u043c\u0438 \u043f\u043e\u043f\u0443\u043b\u044f\u0440\u0438\u0437\u0438\u0440\u043e\u0432\u0430\u043b\u0438 \u043e\u043d\u043b\u0430\u0439\u043d-\u0441\u0435\u0440\u0432\u0438\u0441\u044b \u0432\u0440\u043e\u0434\u0435 Human Benchmark, \u0430 \u043d\u0435 \u043e\u0434\u0438\u043d \u043a\u043e\u043d\u043a\u0440\u0435\u0442\u043d\u044b\u0439 \u0447\u0435\u043b\u043e\u0432\u0435\u043a.",methods:"\u0420\u0430\u0437\u0431\u0438\u0432\u0430\u0439\u0442\u0435 \u0446\u0435\u043f\u043e\u0447\u043a\u0443 \u043d\u0430 \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u0435 \u0433\u0440\u0443\u043f\u043f\u044b \u043f\u043e \u0434\u0432\u0430-\u0442\u0440\u0438 \u044d\u043b\u0435\u043c\u0435\u043d\u0442\u0430, \u0430 \u043d\u0435 \u0437\u0430\u043f\u043e\u043c\u0438\u043d\u0430\u0439\u0442\u0435 \u043a\u0430\u0436\u0434\u044b\u0439 \u043f\u043e \u043e\u0442\u0434\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u0438, \u0438 \u043f\u0440\u0438\u0432\u044f\u0437\u044b\u0432\u0430\u0439\u0442\u0435 \u043a \u043a\u0430\u0436\u0434\u043e\u0439 \u0433\u0440\u0443\u043f\u043f\u0435 \u0441\u0432\u043e\u0439 \u0440\u0438\u0442\u043c \u0438\u043b\u0438 \u043c\u0438\u043d\u0438-\u0441\u044e\u0436\u0435\u0442, \u0447\u0442\u043e\u0431\u044b \u043e\u043d\u0430 \u0434\u0435\u0440\u0436\u0430\u043b\u0430\u0441\u044c. \u041f\u0440\u043e\u0433\u043e\u0432\u0430\u0440\u0438\u0432\u0430\u0439\u0442\u0435 \u043f\u043e\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c \u043f\u0440\u043e \u0441\u0435\u0431\u044f, \u043f\u043e\u043a\u0430 \u043e\u043d\u0430 \u043f\u043e\u043a\u0430\u0437\u044b\u0432\u0430\u0435\u0442\u0441\u044f, \u0434\u0435\u0440\u0436\u0438\u0442\u0435 \u0432\u0437\u0433\u043b\u044f\u0434 \u0440\u0430\u0441\u0441\u043b\u0430\u0431\u043b\u0435\u043d\u043d\u044b\u043c, \u043e\u0445\u0432\u0430\u0442\u044b\u0432\u0430\u044f \u0432\u0441\u0451 \u043f\u043e\u043b\u0435 \u0441\u0440\u0430\u0437\u0443, \u0438 \u043d\u0430 \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u0435\u0434\u0435\u043d\u0438\u0438 \u043d\u0435 \u0441\u043f\u0435\u0448\u0438\u0442\u0435 \u2014 \u0441\u043f\u0435\u0448\u043a\u0430 \u0447\u0430\u0449\u0435 \u0432\u0441\u0435\u0433\u043e \u0438 \u043b\u043e\u043c\u0430\u0435\u0442 \u043f\u043e\u0440\u044f\u0434\u043e\u043a.",duration:"\u041a\u043e\u0440\u043e\u0442\u043a\u0438\u0435 \u0447\u0430\u0441\u0442\u044b\u0435 \u043f\u043e\u0434\u0445\u043e\u0434\u044b \u0440\u0430\u0431\u043e\u0442\u0430\u044e\u0442 \u043b\u0443\u0447\u0448\u0435 \u043c\u0430\u0440\u0430\u0444\u043e\u043d\u043e\u0432: \u043f\u044f\u0442\u044c-\u0434\u0435\u0441\u044f\u0442\u044c \u043c\u0438\u043d\u0443\u0442 \u0432 \u0434\u0435\u043d\u044c \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0440\u0430\u0437 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e \u2014 \u044d\u0442\u043e\u0433\u043e \u0434\u043e\u0441\u0442\u0430\u0442\u043e\u0447\u043d\u043e. \u041e\u0441\u0442\u0430\u043d\u0430\u0432\u043b\u0438\u0432\u0430\u0439\u0442\u0435\u0441\u044c, \u043a\u0430\u043a \u0442\u043e\u043b\u044c\u043a\u043e \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u044c \u043d\u0430\u0447\u0438\u043d\u0430\u0435\u0442 \u043f\u0430\u0434\u0430\u0442\u044c: \u043f\u0440\u043e\u0434\u0430\u0432\u043b\u0438\u0432\u0430\u0442\u044c \u0447\u0435\u0440\u0435\u0437 \u0441\u0438\u043b\u044c\u043d\u0443\u044e \u0443\u0441\u0442\u0430\u043b\u043e\u0441\u0442\u044c \u2014 \u0437\u043d\u0430\u0447\u0438\u0442 \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u0440\u0430\u0437\u0434\u0440\u0430\u0436\u0435\u043d\u0438\u0435, \u0430 \u043d\u0435 \u043f\u0430\u043c\u044f\u0442\u044c.",research:"\u0414\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432\u0430 \u0441\u0438\u043b\u044c\u043d\u0435\u0435 \u0432\u0441\u0435\u0433\u043e \u0440\u043e\u0432\u043d\u043e \u0434\u043b\u044f \u0442\u043e\u0433\u043e, \u0447\u0435\u0433\u043e \u0438 \u0436\u0434\u0451\u0448\u044c: \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u044f\u0441\u044c, \u0432\u044b \u0437\u0430\u043c\u0435\u0442\u043d\u043e \u043b\u0443\u0447\u0448\u0435 \u0437\u0430\u043f\u043e\u043c\u0438\u043d\u0430\u0435\u0442\u0435 \u043f\u043e\u0434\u043e\u0431\u043d\u044b\u0435 \u043f\u043e\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u0438. \u0421 \u0433\u0440\u043e\u043c\u043a\u0438\u043c\u0438 \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f\u043c\u0438 \u0432\u0441\u0451 \u043a\u0443\u0434\u0430 \u0445\u0443\u0436\u0435: \u0438\u0437\u0432\u0435\u0441\u0442\u043d\u044b\u0435 \u043c\u0435\u0442\u0430-\u0430\u043d\u0430\u043b\u0438\u0437\u044b (Melby-Lervag \u0438 Hulme, 2016) \u043f\u043e\u043a\u0430\u0437\u0430\u043b\u0438, \u0447\u0442\u043e \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0430 \u043e\u0431\u044a\u0451\u043c\u0430 \u0438 \u0440\u0430\u0431\u043e\u0447\u0435\u0439 \u043f\u0430\u043c\u044f\u0442\u0438 \u043d\u0435 \u043f\u043e\u0432\u044b\u0448\u0430\u0435\u0442 \u043d\u0430\u0434\u0451\u0436\u043d\u043e \u043e\u0431\u0449\u0438\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0438 \u043d\u0435 \u0434\u0430\u0451\u0442 \u0448\u0438\u0440\u043e\u043a\u043e\u0433\u043e \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0430 \u043d\u0430 \u0440\u0435\u0430\u043b\u044c\u043d\u044b\u0435 \u0434\u0435\u043b\u0430, \u0430 \u0440\u044f\u0434 \u0440\u0435\u0437\u043e\u043d\u0430\u043d\u0441\u043d\u044b\u0445 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u0439 \u0441 \u0442\u0430\u043a\u0438\u043c\u0438 \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f\u043c\u0438 \u043d\u0435 \u0443\u0434\u0430\u043b\u043e\u0441\u044c \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u0435\u0441\u0442\u0438 \u2014 \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u043a \u043b\u044e\u0431\u044b\u043c \u0433\u0440\u043e\u043c\u043a\u0438\u043c \u0437\u0430\u044f\u0432\u043b\u0435\u043d\u0438\u044f\u043c \u0441\u0442\u043e\u0438\u0442 \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u044c\u0441\u044f \u043e\u0441\u0442\u043e\u0440\u043e\u0436\u043d\u043e.",rec:"\u041d\u0435\u0434\u0435\u043b\u044e-\u0434\u0440\u0443\u0433\u0443\u044e \u0446\u0435\u043b\u0435\u043d\u0430\u043f\u0440\u0430\u0432\u043b\u0435\u043d\u043d\u043e \u043e\u0442\u0440\u0430\u0431\u0430\u0442\u044b\u0432\u0430\u0439\u0442\u0435 \u0440\u0430\u0437\u0431\u0438\u0432\u043a\u0443 \u043d\u0430 \u0433\u0440\u0443\u043f\u043f\u044b, \u0430 \u043f\u043e\u0442\u043e\u043c \u0441\u043b\u0435\u0434\u0438\u0442\u0435 \u0437\u0430 \u0441\u0432\u043e\u0438\u043c \u043e\u0431\u044a\u0451\u043c\u043e\u043c \u043f\u0430\u043c\u044f\u0442\u0438, \u0430 \u043d\u0435 \u043f\u0440\u043e\u0441\u0442\u043e \u0433\u043e\u043d\u0438\u0442\u0435\u0441\u044c \u0437\u0430 \u0440\u0435\u043a\u043e\u0440\u0434\u043e\u043c \u043f\u043e \u0441\u044b\u0440\u043e\u043c\u0443 \u0437\u0430\u043f\u043e\u043c\u0438\u043d\u0430\u043d\u0438\u044e.",faq:[["\u0421\u0442\u0430\u043d\u0443 \u043b\u0438 \u044f \u0432 \u0446\u0435\u043b\u043e\u043c \u0443\u043c\u043d\u0435\u0435?","\u0427\u0435\u0441\u0442\u043d\u043e \u2014 \u043d\u0435\u0442, \u0432 \u0448\u0438\u0440\u043e\u043a\u043e\u043c \u0441\u043c\u044b\u0441\u043b\u0435. \u0417\u0430\u043f\u043e\u043c\u0438\u043d\u0430\u0442\u044c \u043f\u043e\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u0438 \u0432\u044b \u0431\u0443\u0434\u0435\u0442\u0435 \u044f\u0432\u043d\u043e \u043b\u0443\u0447\u0448\u0435, \u0438 \u044d\u0442\u043e \u0443\u0436\u0435 \u0447\u0435\u0433\u043e-\u0442\u043e \u0441\u0442\u043e\u0438\u0442, \u043d\u043e \u0434\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432 \u0442\u043e\u0433\u043e, \u0447\u0442\u043e \u044d\u0442\u043e \u043f\u043e\u0434\u043d\u0438\u043c\u0430\u0435\u0442 IQ \u0438\u043b\u0438 \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0438\u0442\u0441\u044f \u043d\u0430 \u043d\u0435 \u0441\u0432\u044f\u0437\u0430\u043d\u043d\u044b\u0435 \u0441 \u0438\u0433\u0440\u043e\u0439 \u043f\u043e\u0432\u0441\u0435\u0434\u043d\u0435\u0432\u043d\u044b\u0435 \u0437\u0430\u0434\u0430\u0447\u0438, \u043d\u0435\u0442."],["\u041f\u043e\u0447\u0435\u043c\u0443 \u044f \u0443\u043f\u0438\u0440\u0430\u044e\u0441\u044c \u0432 \u043f\u043e\u0442\u043e\u043b\u043e\u043a \u043d\u0430 \u043e\u043f\u0440\u0435\u0434\u0435\u043b\u0451\u043d\u043d\u043e\u0439 \u0434\u043b\u0438\u043d\u0435?","\u042d\u0442\u043e \u0438 \u0435\u0441\u0442\u044c \u043e\u0431\u044a\u0451\u043c \u0432\u0430\u0448\u0435\u0439 \u0440\u0430\u0431\u043e\u0447\u0435\u0439 \u043f\u0430\u043c\u044f\u0442\u0438, \u0438 \u043e\u043d \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043d\u043d\u043e \u043e\u0433\u0440\u0430\u043d\u0438\u0447\u0435\u043d \u2014 \u0447\u0430\u0441\u0442\u043e \u044d\u0442\u043e \u0438\u0437\u0432\u0435\u0441\u0442\u043d\u044b\u0439 \u0434\u0438\u0430\u043f\u0430\u0437\u043e\u043d \u0441\u0435\u043c\u044c \u043f\u043b\u044e\u0441-\u043c\u0438\u043d\u0443\u0441 \u0434\u0432\u0430. \u0420\u0430\u0437\u0431\u0438\u0432\u043a\u0430 \u043d\u0430 \u0433\u0440\u0443\u043f\u043f\u044b \u0438 \u043f\u0440\u043e\u0433\u043e\u0432\u0430\u0440\u0438\u0432\u0430\u043d\u0438\u0435 \u043d\u0435\u043c\u043d\u043e\u0433\u043e \u0435\u0433\u043e \u0440\u0430\u0437\u0434\u0432\u0438\u0433\u0430\u044e\u0442, \u043d\u043e \u043f\u043e\u0442\u043e\u043b\u043e\u043a \u0435\u0441\u0442\u044c \u0443 \u0432\u0441\u0435\u0445, \u0442\u0430\u043a \u0447\u0442\u043e \u0432\u043e\u0441\u043f\u0440\u0438\u043d\u0438\u043c\u0430\u0439\u0442\u0435 \u0435\u0433\u043e \u043a\u0430\u043a \u043b\u0438\u0447\u043d\u044b\u0439 \u043e\u0440\u0438\u0435\u043d\u0442\u0438\u0440, \u0430 \u043d\u0435 \u043a\u0430\u043a \u043d\u0435\u0443\u0434\u0430\u0447\u0443."],["\u0427\u0442\u043e \u0432\u0430\u0436\u043d\u0435\u0435 \u2014 \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0438\u0442\u044c \u0431\u044b\u0441\u0442\u0440\u043e \u0438\u043b\u0438 \u0442\u043e\u0447\u043d\u043e?","\u0422\u043e\u0447\u043d\u043e. \u0426\u0435\u043f\u043e\u0447\u043a\u0430 \u0440\u0430\u0441\u0442\u0451\u0442 \u0442\u043e\u043b\u044c\u043a\u043e \u043f\u0440\u0438 \u0431\u0435\u0437\u043e\u0448\u0438\u0431\u043e\u0447\u043d\u043e\u043c \u043f\u043e\u0432\u0442\u043e\u0440\u0435, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u0441\u043f\u043e\u043a\u043e\u0439\u043d\u043e\u0435 \u0432\u0435\u0440\u043d\u043e\u0435 \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u0435\u0434\u0435\u043d\u0438\u0435 \u0432\u0441\u0435\u0433\u0434\u0430 \u043b\u0443\u0447\u0448\u0435 \u0431\u044b\u0441\u0442\u0440\u043e\u0433\u043e \u0438 \u043d\u0435\u0431\u0440\u0435\u0436\u043d\u043e\u0433\u043e, \u0430 \u0441\u043f\u0435\u0448\u043a\u0430 \u2014 \u0433\u043b\u0430\u0432\u043d\u0430\u044f \u043f\u0440\u0438\u0447\u0438\u043d\u0430, \u043f\u043e \u043a\u043e\u0442\u043e\u0440\u043e\u0439 \u043e\u0431\u0440\u044b\u0432\u0430\u0435\u0442\u0441\u044f \u0441\u0435\u0440\u0438\u044f."]],variants:"\u0421\u0440\u0435\u0434\u0438 \u0440\u0430\u0441\u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0451\u043d\u043d\u044b\u0445 \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u043e\u0432 \u2014 \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u0435\u0434\u0435\u043d\u0438\u0435 \u0432 \u043f\u0440\u044f\u043c\u043e\u043c \u0438 \u043e\u0431\u0440\u0430\u0442\u043d\u043e\u043c \u043f\u043e\u0440\u044f\u0434\u043a\u0435 (\u043f\u043e\u0432\u0442\u043e\u0440\u0438\u0442\u044c \u043a\u0430\u043a \u0431\u044b\u043b\u043e \u0438\u043b\u0438 \u0437\u0430\u0434\u043e\u043c \u043d\u0430\u043f\u0435\u0440\u0451\u0434), \u0446\u0435\u043f\u043e\u0447\u043a\u0438 \u0438\u0437 \u0446\u0438\u0444\u0440 \u0438\u043b\u0438 \u0431\u0443\u043a\u0432 \u0432\u043c\u0435\u0441\u0442\u043e \u043f\u043b\u0438\u0442\u043e\u043a, \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0435 \u043f\u043e\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u0438 \u0432 \u0441\u0442\u0438\u043b\u0435 \u041a\u043e\u0440\u0441\u0438, \u0430 \u0442\u0430\u043a\u0436\u0435 \u0446\u0432\u0435\u0442\u043e\u0432\u044b\u0435 \u0438 \u0437\u0432\u0443\u043a\u043e\u0432\u044b\u0435 \u0440\u044f\u0434\u044b, \u043a\u0430\u043a \u0432 \u043a\u043b\u0430\u0441\u0441\u0438\u0447\u0435\u0441\u043a\u0438\u0445 \u044d\u043b\u0435\u043a\u0442\u0440\u043e\u043d\u043d\u044b\u0445 \u0438\u0433\u0440\u0430\u0445 \u043d\u0430 \u043f\u0430\u043c\u044f\u0442\u044c. \u0412 \u0443\u0441\u043b\u043e\u0436\u043d\u0451\u043d\u043d\u044b\u0445 \u0440\u0435\u0436\u0438\u043c\u0430\u0445 \u0441\u043e\u043a\u0440\u0430\u0449\u0430\u044e\u0442 \u0432\u0440\u0435\u043c\u044f \u043f\u043e\u043a\u0430\u0437\u0430 \u0438\u043b\u0438 \u0432\u0441\u0442\u0430\u0432\u043b\u044f\u044e\u0442 \u043e\u0442\u0432\u043b\u0435\u043a\u0430\u044e\u0449\u0438\u0435 \u0448\u0430\u0433\u0438 \u043c\u0435\u0436\u0434\u0443 \u043f\u043e\u043a\u0430\u0437\u043e\u043c \u0438 \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u0435\u0434\u0435\u043d\u0438\u0435\u043c."},en:{about:"Span: Sequence Memory shows you a growing sequence of items lighting up one after another, and your job is to play it back in the exact same order. Each round you reproduce correctly, the sequence gets one step longer, so the game keeps pushing right up to the limit of what you can hold.",benefit:"It trains short-term and working memory for ordered information, plus the focused attention you need to register each item without your mind wandering. In plain terms, it stretches how much you can hold in your head at once and keep in the right order.",history:"It grows out of the memory-span tradition that began in experimental psychology in the late 19th century, when researchers started measuring the longest sequence a person could repeat back. The spatial, tile-lighting version became familiar to a wide audience through online benchmark tests in the 2010s, and it echoes the old electronic memory toys where you copy an ever-longer string of lights and sounds.",creator:"There is no single inventor of this exact game. The underlying immediate serial recall task is usually credited to Joseph Jacobs, who measured digit span in 1887; the visual-spatial sequence form descends from Philip Corsi's block-tapping test (1972). The familiar light-up-tiles version was popularised by online tools such as Human Benchmark, not by one named author.",methods:"Chunk the sequence into small groups of two or three rather than memorising every item separately, and give each chunk a quick rhythm or story so it sticks. Subvocally rehearse the run while it plays, keep your eyes relaxed so you take in the whole board, and slow down on playback rather than rushing and breaking your own order.",duration:"Short, frequent sessions beat marathons: five to ten minutes a day, a handful of times a week, is plenty. Stop once your accuracy starts sliding, since pushing through heavy fatigue mostly trains frustration rather than memory.",research:"Evidence is strongest for exactly what you would expect: practise this and you get noticeably better at remembering sequences like this one. The bigger claims are far shakier; well-known meta-analyses (Melby-Lervag and Hulme, 2016) found that memory-span and working-memory training does not reliably raise general intelligence or produce broad real-world transfer, and several headline studies promising such gains failed to replicate, so treat any sweeping promise with caution.",rec:"Train chunking deliberately for a week or two, then watch your span instead of just chasing a high score on raw recall.",faq:[["Does this make me smarter overall?","Honestly, no, not in any broad sense. You will get clearly better at remembering sequences, and that is worth something, but the evidence does not support claims that it raises IQ or transfers to unrelated everyday tasks."],["Why do I hit a wall at a certain length?","That is your working-memory span, and it is naturally limited, often around the well-known seven-plus-or-minus-two range. Chunking and rehearsal can push it a little, but everyone runs into a ceiling, so treat it as a personal benchmark rather than a failure."],["Is it better to recall fast or accurately?","Accurately. The sequence only grows when you reproduce it without errors, so a calm, correct playback beats a fast, sloppy one every time, and rushing is the single most common reason people break their own streak."]],variants:"Common variations include forward versus backward recall (repeat the order, or reverse it), digit or letter span instead of tiles, spatial Corsi-style block sequences, and colour or sound sequences as in classic electronic memory games. Harder modes shorten the display time or add distractor steps between showing and recalling."},es:{about:"Amplitud: Memoria de Secuencias te muestra una secuencia creciente de elementos que se iluminan uno tras otro, y tu tarea es reproducirla exactamente en el mismo orden. Cada ronda que reproduces correctamente, la secuencia se alarga un paso m\xe1s, as\xed que el juego sigue empuj\xe1ndote justo hasta el l\xedmite de lo que puedes retener.",benefit:"Entrena la memoria a corto plazo y de trabajo para informaci\xf3n ordenada, adem\xe1s de la atenci\xf3n concentrada que necesitas para registrar cada elemento sin que la mente se distraiga. En t\xe9rminos sencillos, estira cu\xe1nto puedes retener en la cabeza a la vez y mantenerlo en el orden correcto.",history:"Surge de la tradici\xf3n de la amplitud de memoria que empez\xf3 en la psicolog\xeda experimental a finales del siglo XIX, cuando los investigadores comenzaron a medir la secuencia m\xe1s larga que una persona pod\xeda repetir. La versi\xf3n espacial, de baldosas que se iluminan, se hizo familiar para un p\xfablico amplio a trav\xe9s de los tests de referencia en l\xednea de la d\xe9cada de 2010, y recuerda a aquellos viejos juguetes electr\xf3nicos de memoria en los que copias una cadena cada vez m\xe1s larga de luces y sonidos.",creator:"No hay un \xfanico inventor de este juego exacto. La tarea subyacente de recuerdo serial inmediato suele atribuirse a Joseph Jacobs, que midi\xf3 la amplitud de d\xedgitos en 1887; la forma de secuencia visoespacial desciende de la prueba de golpeteo de bloques de Philip Corsi (1972). La conocida versi\xf3n de baldosas que se iluminan fue popularizada por herramientas en l\xednea como Human Benchmark, no por un autor con nombre propio.",methods:"Agrupa la secuencia en peque\xf1os grupos de dos o tres en lugar de memorizar cada elemento por separado, y dale a cada grupo un ritmo o una historia r\xe1pida para que se fije. Repasa subvocalmente la serie mientras se reproduce, mant\xe9n la mirada relajada para abarcar todo el tablero, y baja el ritmo al reproducir en vez de correr y romper tu propio orden.",duration:"Las sesiones cortas y frecuentes ganan a los maratones: de cinco a diez minutos al d\xeda, un pu\xf1ado de veces por semana, es de sobra. Para cuando tu precisi\xf3n empiece a caer, ya que insistir con una fatiga intensa entrena m\xe1s la frustraci\xf3n que la memoria.",research:"La evidencia es m\xe1s s\xf3lida justo en lo que cabr\xeda esperar: practica esto y mejoras notablemente en recordar secuencias como esta. Las afirmaciones m\xe1s grandes son mucho m\xe1s endebles; metaan\xe1lisis muy conocidos (Melby-Lervag y Hulme, 2016) hallaron que el entrenamiento de la amplitud de memoria y de la memoria de trabajo no eleva de forma fiable la inteligencia general ni produce una transferencia amplia al mundo real, y varios estudios estelares que promet\xedan esas mejoras fracasaron al replicarse, as\xed que toma con cautela cualquier promesa rotunda.",rec:"Entrena el agrupamiento de forma deliberada durante una o dos semanas, y luego observa tu amplitud en lugar de solo perseguir una puntuaci\xf3n alta en recuerdo en bruto.",faq:[["\xbfEsto me hace m\xe1s inteligente en general?","Honestamente, no, no en ning\xfan sentido amplio. Mejorar\xe1s claramente en recordar secuencias, y eso tiene su valor, pero la evidencia no respalda las afirmaciones de que eleva el CI o se transfiere a tareas cotidianas no relacionadas."],["\xbfPor qu\xe9 choco contra un muro en cierta longitud?","Esa es tu amplitud de memoria de trabajo, y est\xe1 limitada de forma natural, a menudo en torno al conocido rango de siete m\xe1s o menos dos. El agrupamiento y el repaso pueden empujarla un poco, pero todo el mundo topa con un techo, as\xed que t\xf3malo como una referencia personal y no como un fracaso."],["\xbfEs mejor recordar r\xe1pido o con precisi\xf3n?","Con precisi\xf3n. La secuencia solo crece cuando la reproduces sin errores, as\xed que una reproducci\xf3n tranquila y correcta gana siempre a una r\xe1pida y descuidada, y apresurarse es la raz\xf3n m\xe1s com\xfan por la que la gente rompe su propia racha."]],variants:"Las variaciones habituales incluyen recuerdo hacia delante frente a hacia atr\xe1s (repetir el orden, o invertirlo), amplitud de d\xedgitos o letras en lugar de baldosas, secuencias espaciales de bloques al estilo Corsi, y secuencias de color o sonido como en los cl\xe1sicos juegos electr\xf3nicos de memoria. Los modos m\xe1s dif\xedciles acortan el tiempo de presentaci\xf3n o a\xf1aden pasos distractores entre mostrar y recordar."},de:{about:"Span: Sequence Memory zeigt dir eine wachsende Folge von Elementen, die nacheinander aufleuchten, und deine Aufgabe ist es, sie in genau derselben Reihenfolge wiederzugeben. Mit jeder Runde, die du korrekt wiedergibst, wird die Folge um einen Schritt l\xe4nger, sodass das Spiel dich immer weiter bis an die Grenze dessen treibt, was du behalten kannst.",benefit:"Es trainiert das Kurzzeit- und Arbeitsged\xe4chtnis f\xfcr geordnete Informationen sowie die fokussierte Aufmerksamkeit, die du brauchst, um jedes Element zu erfassen, ohne dass deine Gedanken abschweifen. Schlicht gesagt erweitert es, wie viel du auf einmal im Kopf behalten und in der richtigen Reihenfolge halten kannst.",history:"Es entstammt der Tradition der Merkspanne, die in der experimentellen Psychologie im sp\xe4ten 19. Jahrhundert begann, als Forscher anfingen, die l\xe4ngste Folge zu messen, die eine Person wiederholen konnte. Die r\xe4umliche Variante mit aufleuchtenden Kacheln wurde durch Online-Benchmark-Tests in den 2010er-Jahren einem breiten Publikum vertraut, und sie erinnert an die alten elektronischen Ged\xe4chtnisspielzeuge, bei denen man eine immer l\xe4ngere Folge aus Lichtern und T\xf6nen nachahmt.",creator:"Es gibt keinen einzelnen Erfinder genau dieses Spiels. Die zugrunde liegende Aufgabe der unmittelbaren seriellen Wiedergabe wird \xfcblicherweise Joseph Jacobs zugeschrieben, der 1887 die Zahlenspanne ma\xdf; die visuell-r\xe4umliche Abfolgeform stammt von Philip Corsis Block-Tapping-Test (1972) ab. Die vertraute Variante mit aufleuchtenden Kacheln wurde durch Online-Werkzeuge wie Human Benchmark popul\xe4r, nicht durch einen einzelnen namentlichen Urheber.",methods:"Fasse die Abfolge in kleine Gruppen von zwei oder drei zusammen, statt jedes Element einzeln auswendig zu lernen, und gib jeder Gruppe einen schnellen Rhythmus oder eine kleine Geschichte, damit sie haften bleibt. Wiederhole die Folge still, w\xe4hrend sie l\xe4uft, halte deinen Blick entspannt, um das gesamte Feld zu erfassen, und verlangsame bei der Wiedergabe, statt zu hetzen und deine eigene Reihenfolge zu zerst\xf6ren.",duration:"Kurze, h\xe4ufige Einheiten schlagen Marathons: f\xfcnf bis zehn Minuten am Tag, ein paar Mal pro Woche, reichen v\xf6llig. H\xf6re auf, sobald deine Genauigkeit nachl\xe4sst, denn bei starker Erm\xfcdung weiterzumachen trainiert vor allem Frust statt Ged\xe4chtnis.",research:"Am st\xe4rksten ist die Beleglage genau f\xfcr das, was man erwarten w\xfcrde: Wenn du dies \xfcbst, wirst du im Merken solcher Abfolgen sp\xfcrbar besser. Die gr\xf6\xdferen Behauptungen sind weitaus wackliger; bekannte Metaanalysen (Melby-Lerv\xe5g und Hulme, 2016) fanden, dass Merkspannen- und Arbeitsged\xe4chtnistraining die allgemeine Intelligenz nicht zuverl\xe4ssig steigert oder breiten Transfer in die reale Welt erzeugt, und mehrere viel beachtete Studien, die solche Zugewinne versprachen, lie\xdfen sich nicht replizieren \u2013 nimm jedes weitreichende Versprechen also mit Vorsicht.",rec:"Trainiere ein bis zwei Wochen lang bewusst das B\xfcndeln in Gruppen und beobachte dann deine Merkspanne, statt nur einer H\xf6chstpunktzahl bei der reinen Wiedergabe hinterherzujagen.",faq:[["Macht mich das insgesamt kl\xfcger?","Ehrlich gesagt nein, nicht im breiten Sinn. Du wirst im Merken von Abfolgen deutlich besser, und das ist etwas wert, aber die Belege st\xfctzen nicht die Behauptung, es erh\xf6he den IQ oder \xfcbertrage sich auf unabh\xe4ngige Alltagsaufgaben."],["Warum sto\xdfe ich bei einer bestimmten L\xe4nge an eine Wand?","Das ist deine Arbeitsged\xe4chtnisspanne, und sie ist naturgem\xe4\xdf begrenzt, oft im Bereich der bekannten Sieben-plus-minus-zwei. B\xfcndeln und Wiederholen k\xf6nnen sie ein wenig dehnen, aber jeder st\xf6\xdft an eine Decke \u2013 sieh es also als pers\xf6nliche Bestmarke, nicht als Versagen."],["Ist es besser, schnell oder genau wiederzugeben?","Genau. Die Folge w\xe4chst nur, wenn du sie fehlerfrei wiedergibst, also schl\xe4gt eine ruhige, korrekte Wiedergabe jedes Mal eine schnelle, schludrige, und Hetzen ist der mit Abstand h\xe4ufigste Grund, warum Leute ihre eigene Serie rei\xdfen lassen."]],variants:"G\xe4ngige Varianten umfassen die Vorw\xe4rts- gegen\xfcber der R\xfcckw\xe4rtswiedergabe (die Reihenfolge wiederholen oder umkehren), Zahlen- oder Buchstabenspanne statt Kacheln, r\xe4umliche Abfolgen im Corsi-Stil mit Bl\xf6cken sowie Farb- oder Tonfolgen wie in klassischen elektronischen Ged\xe4chtnisspielen. Schwerere Modi verk\xfcrzen die Anzeigedauer oder f\xfcgen zwischen Zeigen und Wiedergeben ablenkende Schritte ein."},pt:{about:"O Span: Sequence Memory mostra uma sequ\xeancia crescente de itens que acendem um ap\xf3s o outro, e a sua tarefa \xe9 reproduzi-la exatamente na mesma ordem. A cada rodada que voc\xea acerta, a sequ\xeancia fica um passo mais longa, ent\xe3o o jogo continua empurrando at\xe9 o limite do que voc\xea consegue reter.",benefit:"Ele treina a mem\xf3ria de curto prazo e de trabalho para informa\xe7\xe3o ordenada, al\xe9m da aten\xe7\xe3o concentrada de que voc\xea precisa para registrar cada item sem a mente vagar. Em termos simples, ele estica o quanto voc\xea consegue reter na cabe\xe7a de uma vez e manter na ordem certa.",history:"Nasce da tradi\xe7\xe3o do span de mem\xf3ria, que come\xe7ou na psicologia experimental no fim do s\xe9culo XIX, quando os pesquisadores passaram a medir a maior sequ\xeancia que uma pessoa conseguia repetir. A vers\xe3o espacial, com pe\xe7as que acendem, ficou conhecida por um amplo p\xfablico atrav\xe9s dos testes de benchmark on-line dos anos 2010, e ecoa os antigos brinquedos eletr\xf4nicos de mem\xf3ria em que voc\xea copia uma cadeia cada vez mais longa de luzes e sons.",creator:"N\xe3o h\xe1 um \xfanico inventor deste jogo espec\xedfico. A tarefa subjacente de recorda\xe7\xe3o serial imediata costuma ser creditada a Joseph Jacobs, que mediu o span de d\xedgitos em 1887; a forma de sequ\xeancia visuoespacial descende do teste de toque de blocos de Philip Corsi (1972). A conhecida vers\xe3o de pe\xe7as que acendem foi popularizada por ferramentas on-line como o Human Benchmark, e n\xe3o por um autor espec\xedfico.",methods:"Agrupe a sequ\xeancia em pequenos grupos de dois ou tr\xeas, em vez de memorizar cada item separadamente, e d\xea a cada grupo um ritmo ou uma historinha r\xe1pida para que ele grude. Ensaie subvocalmente a sequ\xeancia enquanto ela passa, mantenha os olhos relaxados para captar o tabuleiro inteiro e desacelere na hora de reproduzir, em vez de se apressar e quebrar a sua pr\xf3pria ordem.",duration:"Sess\xf5es curtas e frequentes vencem as maratonas: de cinco a dez minutos por dia, algumas vezes por semana, j\xe1 bastam. Pare quando a sua precis\xe3o come\xe7ar a cair, j\xe1 que insistir sob fadiga pesada treina mais a frustra\xe7\xe3o do que a mem\xf3ria.",research:"As evid\xeancias s\xe3o mais fortes exatamente para o que se espera: pratique isto e voc\xea fica visivelmente melhor em lembrar sequ\xeancias como esta. As alega\xe7\xf5es maiores s\xe3o bem mais fr\xe1geis; meta-an\xe1lises conhecidas (Melby-Lervag e Hulme, 2016) constataram que o treino de span de mem\xf3ria e de mem\xf3ria de trabalho n\xe3o aumenta de forma confi\xe1vel a intelig\xeancia geral nem produz transfer\xeancia ampla para o mundo real, e v\xe1rios estudos de destaque que prometiam tais ganhos fracassaram em ser replicados, ent\xe3o encare qualquer promessa abrangente com cautela.",rec:"Treine o agrupamento deliberadamente por uma ou duas semanas e ent\xe3o acompanhe o seu span, em vez de s\xf3 perseguir uma pontua\xe7\xe3o alta de recorda\xe7\xe3o bruta.",faq:[["Isso me deixa mais inteligente no geral?","Honestamente, n\xe3o, em nenhum sentido amplo. Voc\xea vai ficar claramente melhor em lembrar sequ\xeancias, e isso vale alguma coisa, mas as evid\xeancias n\xe3o sustentam alega\xe7\xf5es de que ele aumenta o QI ou se transfere para tarefas do dia a dia n\xe3o relacionadas."],["Por que bato numa parede em certo comprimento?","Esse \xe9 o seu span de mem\xf3ria de trabalho, e ele \xe9 naturalmente limitado, muitas vezes em torno da conhecida faixa de sete mais ou menos dois. Agrupar e ensaiar pode empurr\xe1-lo um pouco, mas todo mundo esbarra num teto, ent\xe3o encare-o como uma marca pessoal, n\xe3o como fracasso."],["\xc9 melhor recordar r\xe1pido ou com precis\xe3o?","Com precis\xe3o. A sequ\xeancia s\xf3 cresce quando voc\xea a reproduz sem erros, ent\xe3o uma reprodu\xe7\xe3o calma e correta vence uma r\xe1pida e desleixada todas as vezes, e correr \xe9 a raz\xe3o mais comum de as pessoas quebrarem a pr\xf3pria sequ\xeancia."]],variants:"Varia\xe7\xf5es comuns incluem recorda\xe7\xe3o direta versus invertida (repetir a ordem ou revert\xea-la), span de d\xedgitos ou de letras em vez de pe\xe7as, sequ\xeancias espaciais ao estilo Corsi e sequ\xeancias de cores ou sons como nos cl\xe1ssicos jogos eletr\xf4nicos de mem\xf3ria. Modos mais dif\xedceis encurtam o tempo de exibi\xe7\xe3o ou inserem passos distratores entre mostrar e recordar."},hi:{about:"Span: Sequence Memory \u0906\u092a\u0915\u094b \u091a\u0940\u091c\u093c\u094b\u0902 \u0915\u093e \u090f\u0915 \u092c\u0922\u093c\u0924\u093e \u0939\u0941\u0906 \u0915\u094d\u0930\u092e \u0926\u093f\u0916\u093e\u0924\u093e \u0939\u0948 \u091c\u094b \u090f\u0915-\u090f\u0915 \u0915\u0930\u0915\u0947 \u091c\u0932\u0924\u093e \u0939\u0948, \u0914\u0930 \u0906\u092a\u0915\u093e \u0915\u093e\u092e \u0939\u0948 \u0909\u0938\u0947 \u0920\u0940\u0915 \u0909\u0938\u0940 \u0915\u094d\u0930\u092e \u092e\u0947\u0902 \u0926\u094b\u0939\u0930\u093e\u0928\u093e\u0964 \u091c\u093f\u0938 \u092d\u0940 \u0926\u094c\u0930 \u0915\u094b \u0906\u092a \u0938\u0939\u0940 \u0926\u094b\u0939\u0930\u093e\u0924\u0947 \u0939\u0948\u0902, \u0915\u094d\u0930\u092e \u090f\u0915 \u0915\u093c\u0926\u092e \u0914\u0930 \u0932\u0902\u092c\u093e \u0939\u094b \u091c\u093e\u0924\u093e \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0916\u0947\u0932 \u0906\u092a\u0915\u094b \u0920\u0940\u0915 \u0909\u0938 \u0938\u0940\u092e\u093e \u0924\u0915 \u0927\u0915\u0947\u0932\u0924\u093e \u0930\u0939\u0924\u093e \u0939\u0948 \u091c\u093f\u0924\u0928\u093e \u0906\u092a \u092e\u0928 \u092e\u0947\u0902 \u0925\u093e\u092e \u0938\u0915\u0924\u0947 \u0939\u0948\u0902\u0964",benefit:"\u092f\u0939 \u0915\u094d\u0930\u092e\u092c\u0926\u094d\u0927 \u091c\u093e\u0928\u0915\u093e\u0930\u0940 \u0915\u0947 \u0932\u093f\u090f \u0905\u0932\u094d\u092a\u0915\u093e\u0932\u093f\u0915 \u0914\u0930 \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932 \u0938\u094d\u092e\u0943\u0924\u093f \u0915\u094b \u0938\u0927\u093e\u0924\u093e \u0939\u0948, \u0938\u093e\u0925 \u0939\u0940 \u0935\u0939 \u090f\u0915\u093e\u0917\u094d\u0930 \u0927\u094d\u092f\u093e\u0928 \u092d\u0940 \u091c\u093f\u0938\u0915\u0940 \u0906\u092a\u0915\u094b \u0939\u0930 \u091a\u0940\u091c\u093c \u0915\u094b \u0926\u0930\u094d\u091c \u0915\u0930\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u091c\u093c\u0930\u0942\u0930\u0924 \u0939\u094b\u0924\u0940 \u0939\u0948, \u092c\u093f\u0928\u093e \u092e\u0928 \u0915\u0947 \u092d\u091f\u0915\u0947\u0964 \u0938\u0940\u0927\u0947 \u0936\u092c\u094d\u0926\u094b\u0902 \u092e\u0947\u0902, \u092f\u0939 \u092c\u0922\u093c\u093e\u0924\u093e \u0939\u0948 \u0915\u093f \u0906\u092a \u090f\u0915 \u092c\u093e\u0930 \u092e\u0947\u0902 \u0905\u092a\u0928\u0947 \u0926\u093f\u092e\u093e\u0917 \u092e\u0947\u0902 \u0915\u093f\u0924\u0928\u093e \u0925\u093e\u092e \u0938\u0915\u0924\u0947 \u0939\u0948\u0902 \u0914\u0930 \u0938\u0939\u0940 \u0915\u094d\u0930\u092e \u092e\u0947\u0902 \u0930\u0916 \u0938\u0915\u0924\u0947 \u0939\u0948\u0902\u0964",history:"\u092f\u0939 \u0938\u094d\u092e\u0943\u0924\u093f-span \u0915\u0940 \u0909\u0938 \u092a\u0930\u0902\u092a\u0930\u093e \u0938\u0947 \u0928\u093f\u0915\u0932\u093e \u0939\u0948 \u091c\u094b 19\u0935\u0940\u0902 \u0938\u0926\u0940 \u0915\u0947 \u0906\u0916\u093c\u093f\u0930 \u092e\u0947\u0902 \u092a\u094d\u0930\u093e\u092f\u094b\u0917\u093f\u0915 \u092e\u0928\u094b\u0935\u093f\u091c\u094d\u091e\u093e\u0928 \u092e\u0947\u0902 \u0936\u0941\u0930\u0942 \u0939\u0941\u0908, \u091c\u092c \u0936\u094b\u0927\u0915\u0930\u094d\u0924\u093e\u0913\u0902 \u0928\u0947 \u0909\u0938 \u0938\u092c\u0938\u0947 \u0932\u0902\u092c\u0947 \u0915\u094d\u0930\u092e \u0915\u094b \u092e\u093e\u092a\u0928\u093e \u0936\u0941\u0930\u0942 \u0915\u093f\u092f\u093e \u091c\u093f\u0938\u0947 \u0915\u094b\u0908 \u0935\u094d\u092f\u0915\u094d\u0924\u093f \u0926\u094b\u0939\u0930\u093e \u0938\u0915\u0924\u093e \u0925\u093e\u0964 \u0938\u094d\u0925\u093e\u0928\u093f\u0915, \u091f\u093e\u0907\u0932-\u091c\u0932\u0928\u0947 \u0935\u093e\u0932\u093e \u0938\u0902\u0938\u094d\u0915\u0930\u0923 2010 \u0915\u0947 \u0926\u0936\u0915 \u092e\u0947\u0902 \u0911\u0928\u0932\u093e\u0907\u0928 \u092c\u0947\u0902\u091a\u092e\u093e\u0930\u094d\u0915 \u092a\u0930\u0940\u0915\u094d\u0937\u0923\u094b\u0902 \u0915\u0947 \u091c\u093c\u0930\u093f\u090f \u090f\u0915 \u092c\u0921\u093c\u0947 \u0926\u0930\u094d\u0936\u0915-\u0935\u0930\u094d\u0917 \u0938\u0947 \u092a\u0930\u093f\u091a\u093f\u0924 \u0939\u0941\u0906, \u0914\u0930 \u092f\u0939 \u0909\u0928 \u092a\u0941\u0930\u093e\u0928\u0947 \u0907\u0932\u0947\u0915\u094d\u091f\u094d\u0930\u0949\u0928\u093f\u0915 \u0938\u094d\u092e\u0943\u0924\u093f-\u0916\u093f\u0932\u094c\u0928\u094b\u0902 \u0915\u0940 \u092f\u093e\u0926 \u0926\u093f\u0932\u093e\u0924\u093e \u0939\u0948 \u091c\u0939\u093e\u0901 \u0906\u092a \u0930\u094b\u0936\u0928\u093f\u092f\u094b\u0902 \u0914\u0930 \u0906\u0935\u093e\u091c\u093c\u094b\u0902 \u0915\u0940 \u090f\u0915 \u0932\u0917\u093e\u0924\u093e\u0930 \u0932\u0902\u092c\u0940 \u0939\u094b\u0924\u0940 \u0936\u0943\u0902\u0916\u0932\u093e \u0915\u0940 \u0928\u0915\u093c\u0932 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902\u0964",creator:"\u0907\u0938 \u0920\u0940\u0915 \u0907\u0938\u0940 \u0916\u0947\u0932 \u0915\u093e \u0915\u094b\u0908 \u090f\u0915 \u0906\u0935\u093f\u0937\u094d\u0915\u093e\u0930\u0915 \u0928\u0939\u0940\u0902 \u0939\u0948\u0964 \u0907\u0938\u0915\u0947 \u092d\u0940\u0924\u0930 \u092c\u0938\u0947 \u0924\u093e\u0924\u094d\u0915\u093e\u0932\u093f\u0915 \u0915\u094d\u0930\u092e\u093f\u0915-\u092f\u093e\u0926 \u0935\u093e\u0932\u0947 \u0915\u093e\u0930\u094d\u092f \u0915\u093e \u0936\u094d\u0930\u0947\u092f \u0906\u092e\u0924\u094c\u0930 \u092a\u0930 Joseph Jacobs \u0915\u094b \u0926\u093f\u092f\u093e \u091c\u093e\u0924\u093e \u0939\u0948, \u091c\u093f\u0928\u094d\u0939\u094b\u0902\u0928\u0947 1887 \u092e\u0947\u0902 digit span \u092e\u093e\u092a\u093e \u0925\u093e; \u0926\u0943\u0936\u094d\u092f-\u0938\u094d\u0925\u093e\u0928\u093f\u0915 \u0915\u094d\u0930\u092e \u0935\u093e\u0932\u093e \u0930\u0942\u092a Philip Corsi \u0915\u0947 block-tapping \u092a\u0930\u0940\u0915\u094d\u0937\u0923 (1972) \u0938\u0947 \u0909\u0924\u0930\u093e \u0939\u0948\u0964 \u091c\u093e\u0928\u093e-\u092a\u0939\u091a\u093e\u0928\u093e \u091f\u093e\u0907\u0932-\u091c\u0932\u0928\u0947 \u0935\u093e\u0932\u093e \u0938\u0902\u0938\u094d\u0915\u0930\u0923 Human Benchmark \u091c\u0948\u0938\u0947 \u0911\u0928\u0932\u093e\u0907\u0928 \u0909\u092a\u0915\u0930\u0923\u094b\u0902 \u0928\u0947 \u0932\u094b\u0915\u092a\u094d\u0930\u093f\u092f \u092c\u0928\u093e\u092f\u093e, \u0928 \u0915\u093f \u0915\u093f\u0938\u0940 \u090f\u0915 \u0928\u093e\u092e\u0940 \u0932\u0947\u0916\u0915 \u0928\u0947\u0964",methods:"\u0939\u0930 \u091a\u0940\u091c\u093c \u0915\u094b \u0905\u0932\u0917-\u0905\u0932\u0917 \u0930\u091f\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u0915\u094d\u0930\u092e \u0915\u094b \u0926\u094b \u092f\u093e \u0924\u0940\u0928 \u0915\u0947 \u091b\u094b\u091f\u0947 \u0938\u092e\u0942\u0939\u094b\u0902 \u092e\u0947\u0902 \u092c\u093e\u0901\u091f \u0932\u0940\u091c\u093f\u090f, \u0914\u0930 \u0939\u0930 \u091f\u0941\u0915\u0921\u093c\u0947 \u0915\u094b \u090f\u0915 \u091d\u091f\u092a\u091f \u0932\u092f \u092f\u093e \u0915\u0939\u093e\u0928\u0940 \u0926\u0947 \u0926\u0940\u091c\u093f\u090f \u0924\u093e\u0915\u093f \u0935\u0939 \u091f\u093f\u0915 \u091c\u093e\u090f\u0964 \u091c\u092c \u0935\u0939 \u091a\u0932 \u0930\u0939\u093e \u0939\u094b \u0924\u092c \u092e\u0928-\u0939\u0940-\u092e\u0928 \u0909\u0938 \u0926\u094c\u0930 \u0915\u094b \u0926\u094b\u0939\u0930\u093e\u0907\u090f, \u0905\u092a\u0928\u0940 \u0906\u0901\u0916\u094b\u0902 \u0915\u094b \u0922\u0940\u0932\u093e \u0930\u0916\u093f\u090f \u0924\u093e\u0915\u093f \u0906\u092a \u092a\u0942\u0930\u093e \u092c\u094b\u0930\u094d\u0921 \u0938\u092e\u0947\u091f \u0938\u0915\u0947\u0902, \u0914\u0930 \u0926\u094b\u0939\u0930\u093e\u0924\u0947 \u0938\u092e\u092f \u091c\u0932\u094d\u0926\u092c\u093e\u091c\u093c\u0940 \u0915\u0930\u0915\u0947 \u0905\u092a\u0928\u093e \u0939\u0940 \u0915\u094d\u0930\u092e \u0924\u094b\u0921\u093c\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u0927\u0940\u092e\u0947 \u0939\u094b\u0907\u090f\u0964",duration:"\u092e\u0948\u0930\u093e\u0925\u0928 \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u0939\u0948\u0902 \u091b\u094b\u091f\u0947, \u092c\u093e\u0930-\u092c\u093e\u0930 \u0915\u0947 \u0938\u0924\u094d\u0930: \u0930\u094b\u091c\u093c \u092a\u093e\u0901\u091a \u0938\u0947 \u0926\u0938 \u092e\u093f\u0928\u091f, \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u0915\u0941\u091b \u092c\u093e\u0930, \u0915\u093e\u092b\u093c\u0940 \u0939\u0948\u0964 \u091c\u092c \u0906\u092a\u0915\u0940 \u0938\u091f\u0940\u0915\u0924\u093e \u0917\u093f\u0930\u0928\u0947 \u0932\u0917\u0947 \u0924\u092c \u0930\u0941\u0915 \u091c\u093e\u0907\u090f, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u092d\u093e\u0930\u0940 \u0925\u0915\u093e\u0928 \u092e\u0947\u0902 \u091c\u093c\u092c\u0930\u0926\u0938\u094d\u0924\u0940 \u0915\u0930\u0928\u093e \u091c\u093c\u094d\u092f\u093e\u0926\u093e\u0924\u0930 \u092f\u093e\u0926\u0926\u093e\u0936\u094d\u0924 \u0915\u0947 \u092c\u091c\u093e\u092f \u091d\u0941\u0901\u091d\u0932\u093e\u0939\u091f \u0915\u094b \u0938\u0927\u093e\u0924\u093e \u0939\u0948\u0964",research:"\u0938\u092c\u0938\u0947 \u092a\u0941\u0916\u093c\u094d\u0924\u093e \u0938\u092c\u0942\u0924 \u0920\u0940\u0915 \u0909\u0938\u0940 \u092c\u093e\u0924 \u0915\u0947 \u0932\u093f\u090f \u0939\u0948 \u091c\u093f\u0938\u0915\u0940 \u0906\u092a \u0909\u092e\u094d\u092e\u0940\u0926 \u0915\u0930\u0947\u0902\u0917\u0947: \u0907\u0938\u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0940\u091c\u093f\u090f \u0914\u0930 \u0906\u092a \u0907\u0938 \u091c\u0948\u0938\u0947 \u0915\u094d\u0930\u092e\u094b\u0902 \u0915\u094b \u092f\u093e\u0926 \u0930\u0916\u0928\u0947 \u092e\u0947\u0902 \u0938\u093e\u092b\u093c \u0924\u094c\u0930 \u092a\u0930 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902\u0964 \u092c\u0921\u093c\u0947 \u0926\u093e\u0935\u0947 \u0915\u0939\u0940\u0902 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0921\u0917\u092e\u0917\u093e\u0924\u0947 \u0939\u0948\u0902; \u091c\u093e\u0928\u0947-\u092e\u093e\u0928\u0947 \u092e\u0947\u091f\u093e-\u0935\u093f\u0936\u094d\u0932\u0947\u0937\u0923 (Melby-Lervag \u0914\u0930 Hulme, 2016) \u092a\u093e\u0924\u0947 \u0939\u0948\u0902 \u0915\u093f \u0938\u094d\u092e\u0943\u0924\u093f-span \u0914\u0930 \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932-\u0938\u094d\u092e\u0943\u0924\u093f \u0915\u0940 \u091f\u094d\u0930\u0947\u0928\u093f\u0902\u0917 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0922\u0902\u0917 \u0938\u0947 \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u092c\u0941\u0926\u094d\u0927\u093f \u0928\u0939\u0940\u0902 \u092c\u0922\u093c\u093e\u0924\u0940 \u0914\u0930 \u0928 \u0939\u0940 \u0935\u094d\u092f\u093e\u092a\u0915 \u0905\u0938\u0932\u0940-\u0926\u0941\u0928\u093f\u092f\u093e \u0915\u093e \u091f\u094d\u0930\u093e\u0902\u0938\u092b\u093c\u0930 \u0926\u0947\u0924\u0940 \u0939\u0948, \u0914\u0930 \u0910\u0938\u0947 \u0932\u093e\u092d\u094b\u0902 \u0915\u093e \u0935\u093e\u0926\u093e \u0915\u0930\u0928\u0947 \u0935\u093e\u0932\u0947 \u0915\u0908 \u0938\u0941\u0930\u094d\u0916\u093c\u093f\u092f\u094b\u0902 \u0935\u093e\u0932\u0947 \u0905\u0927\u094d\u092f\u092f\u0928 \u0926\u094b\u0939\u0930\u093e\u0928\u0947 \u092a\u0930 \u091f\u093f\u0915 \u0928\u0939\u0940\u0902 \u092a\u093e\u090f, \u0907\u0938\u0932\u093f\u090f \u0915\u093f\u0938\u0940 \u092d\u0940 \u092c\u0921\u093c\u0947-\u092c\u0921\u093c\u0947 \u0935\u093e\u0926\u0947 \u0915\u094b \u0938\u093e\u0935\u0927\u093e\u0928\u0940 \u0938\u0947 \u0932\u0940\u091c\u093f\u090f\u0964",rec:"\u090f\u0915-\u0926\u094b \u0939\u092b\u093c\u094d\u0924\u0947 \u0924\u0915 \u091c\u093e\u0928-\u092c\u0942\u091d\u0915\u0930 \u091f\u0941\u0915\u0921\u093c\u094b\u0902 \u092e\u0947\u0902 \u092c\u093e\u0901\u091f\u0928\u0947 (chunking) \u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0940\u091c\u093f\u090f, \u092b\u093f\u0930 \u0915\u094b\u0930\u0940 \u092f\u093e\u0926 \u092a\u0930 \u090a\u0901\u091a\u0947 \u0938\u094d\u0915\u094b\u0930 \u0915\u0947 \u092a\u0940\u091b\u0947 \u092d\u093e\u0917\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u0905\u092a\u0928\u0947 span \u092a\u0930 \u0928\u091c\u093c\u0930 \u0930\u0916\u093f\u090f\u0964",faq:[["\u0915\u094d\u092f\u093e \u0907\u0938\u0938\u0947 \u092e\u0948\u0902 \u0915\u0941\u0932 \u092e\u093f\u0932\u093e\u0915\u0930 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0939\u094b\u0936\u093f\u092f\u093e\u0930 \u092c\u0928 \u091c\u093e\u0924\u093e \u0939\u0942\u0901?","\u0908\u092e\u093e\u0928\u0926\u093e\u0930\u0940 \u0938\u0947 \u0915\u0939\u0947\u0902 \u0924\u094b, \u0928\u0939\u0940\u0902, \u0915\u093f\u0938\u0940 \u0935\u094d\u092f\u093e\u092a\u0915 \u0905\u0930\u094d\u0925 \u092e\u0947\u0902 \u0928\u0939\u0940\u0902\u0964 \u0906\u092a \u0915\u094d\u0930\u092e\u094b\u0902 \u0915\u094b \u092f\u093e\u0926 \u0930\u0916\u0928\u0947 \u092e\u0947\u0902 \u0938\u093e\u092b\u093c \u0924\u094c\u0930 \u092a\u0930 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u090f\u0901\u0917\u0947, \u0914\u0930 \u0907\u0938\u0915\u0940 \u0905\u092a\u0928\u0940 \u0915\u0940\u092e\u0924 \u0939\u0948, \u092a\u0930 \u0938\u092c\u0942\u0924 \u0907\u0928 \u0926\u093e\u0935\u094b\u0902 \u0915\u093e \u0938\u092e\u0930\u094d\u0925\u0928 \u0928\u0939\u0940\u0902 \u0915\u0930\u0924\u0947 \u0915\u093f \u092f\u0939 IQ \u092c\u0922\u093c\u093e\u0924\u093e \u0939\u0948 \u092f\u093e \u0905\u0938\u0902\u092c\u0902\u0927\u093f\u0924 \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0947 \u0915\u093e\u092e\u094b\u0902 \u0924\u0915 \u092a\u0939\u0941\u0901\u091a\u0924\u093e \u0939\u0948\u0964"],["\u090f\u0915 \u0916\u093c\u093e\u0938 \u0932\u0902\u092c\u093e\u0908 \u092a\u0930 \u092e\u0948\u0902 \u0926\u0940\u0935\u093e\u0930 \u0938\u0947 \u0915\u094d\u092f\u094b\u0902 \u091f\u0915\u0930\u093e \u091c\u093e\u0924\u093e \u0939\u0942\u0901?","\u0935\u0939\u0940 \u0906\u092a\u0915\u0940 \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932-\u0938\u094d\u092e\u0943\u0924\u093f \u0915\u0940 \u0938\u0940\u092e\u093e \u0939\u0948, \u0914\u0930 \u092f\u0939 \u0938\u094d\u0935\u093e\u092d\u093e\u0935\u093f\u0915 \u0930\u0942\u092a \u0938\u0947 \u0938\u0940\u092e\u093f\u0924 \u0939\u094b\u0924\u0940 \u0939\u0948, \u0905\u0915\u094d\u0938\u0930 \u091c\u093e\u0928\u0947-\u092e\u093e\u0928\u0947 \u0938\u093e\u0924-\u0927\u0928-\u092f\u093e-\u0918\u091f\u093e\u0935-\u0926\u094b \u0915\u0947 \u0926\u093e\u092f\u0930\u0947 \u0915\u0947 \u0906\u0938\u092a\u093e\u0938\u0964 \u091f\u0941\u0915\u0921\u093c\u094b\u0902 \u092e\u0947\u0902 \u092c\u093e\u0901\u091f\u0928\u093e \u0914\u0930 \u0926\u094b\u0939\u0930\u093e\u0935 \u0907\u0938\u0947 \u0925\u094b\u0921\u093c\u093e \u0906\u0917\u0947 \u0927\u0915\u0947\u0932 \u0938\u0915\u0924\u0947 \u0939\u0948\u0902, \u092a\u0930 \u0939\u0930 \u0915\u094b\u0908 \u090f\u0915 \u091b\u0924 \u0938\u0947 \u091f\u0915\u0930\u093e\u0924\u093e \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0907\u0938\u0947 \u0928\u093e\u0915\u093e\u092e\u0940 \u0915\u0947 \u092c\u091c\u093e\u092f \u090f\u0915 \u0928\u093f\u091c\u0940 \u092c\u0947\u0902\u091a\u092e\u093e\u0930\u094d\u0915 \u092e\u093e\u0928\u093f\u090f\u0964"],["\u0924\u0947\u091c\u093c \u092f\u093e\u0926 \u0915\u0930\u0928\u093e \u092c\u0947\u0939\u0924\u0930 \u0939\u0948 \u092f\u093e \u0938\u0939\u0940-\u0938\u0939\u0940?","\u0938\u0939\u0940-\u0938\u0939\u0940\u0964 \u0915\u094d\u0930\u092e \u0924\u092d\u0940 \u092c\u0922\u093c\u0924\u093e \u0939\u0948 \u091c\u092c \u0906\u092a \u0909\u0938\u0947 \u092c\u093f\u0928\u093e \u0917\u093c\u0932\u0924\u0940 \u0926\u094b\u0939\u0930\u093e \u0926\u0947\u0924\u0947 \u0939\u0948\u0902, \u0907\u0938\u0932\u093f\u090f \u090f\u0915 \u0936\u093e\u0902\u0924, \u0938\u0939\u0940 \u0926\u094b\u0939\u0930\u093e\u0935 \u0939\u0930 \u092c\u093e\u0930 \u090f\u0915 \u0924\u0947\u091c\u093c, \u0932\u093e\u092a\u0930\u0935\u093e\u0939 \u0926\u094b\u0939\u0930\u093e\u0935 \u0915\u094b \u092e\u093e\u0924 \u0926\u0947\u0924\u093e \u0939\u0948, \u0914\u0930 \u091c\u0932\u094d\u0926\u092c\u093e\u091c\u093c\u0940 \u0939\u0940 \u0935\u0939 \u0938\u092c\u0938\u0947 \u0906\u092e \u0935\u091c\u0939 \u0939\u0948 \u091c\u093f\u0938\u0938\u0947 \u0932\u094b\u0917 \u0905\u092a\u0928\u093e \u0939\u0940 \u0938\u093f\u0932\u0938\u093f\u0932\u093e \u0924\u094b\u0921\u093c \u092c\u0948\u0920\u0924\u0947 \u0939\u0948\u0902\u0964"]],variants:"\u0906\u092e \u092c\u0926\u0932\u093e\u0935\u094b\u0902 \u092e\u0947\u0902 \u0936\u093e\u092e\u093f\u0932 \u0939\u0948\u0902 \u0906\u0917\u0947 \u092c\u0928\u093e\u092e \u0909\u0932\u094d\u091f\u0940 \u092f\u093e\u0926 (\u0915\u094d\u0930\u092e \u0926\u094b\u0939\u0930\u093e\u0928\u093e, \u092f\u093e \u0909\u0938\u0947 \u0909\u0932\u094d\u091f\u093e \u0915\u0930\u0928\u093e), \u091f\u093e\u0907\u0932\u094b\u0902 \u0915\u0947 \u092c\u091c\u093e\u092f \u0905\u0902\u0915 \u092f\u093e \u0905\u0915\u094d\u0937\u0930 span, \u0938\u094d\u0925\u093e\u0928\u093f\u0915 Corsi-\u0936\u0948\u0932\u0940 \u0915\u0947 \u092c\u094d\u0932\u0949\u0915-\u0915\u094d\u0930\u092e, \u0914\u0930 \u0915\u094d\u0932\u093e\u0938\u093f\u0915 \u0907\u0932\u0947\u0915\u094d\u091f\u094d\u0930\u0949\u0928\u093f\u0915 \u0938\u094d\u092e\u0943\u0924\u093f-\u0916\u0947\u0932\u094b\u0902 \u091c\u0948\u0938\u0947 \u0930\u0902\u0917 \u092f\u093e \u0927\u094d\u0935\u0928\u093f \u0915\u0947 \u0915\u094d\u0930\u092e\u0964 \u0915\u0920\u093f\u0928 \u092e\u094b\u0921 \u092a\u094d\u0930\u0926\u0930\u094d\u0936\u0928 \u0915\u093e \u0938\u092e\u092f \u0918\u091f\u093e \u0926\u0947\u0924\u0947 \u0939\u0948\u0902 \u092f\u093e \u0926\u093f\u0916\u093e\u0928\u0947 \u0914\u0930 \u092f\u093e\u0926 \u0915\u0930\u0928\u0947 \u0915\u0947 \u092c\u0940\u091a \u092d\u091f\u0915\u093e\u0928\u0947 \u0935\u093e\u0932\u0947 \u091a\u0930\u0923 \u091c\u094b\u0921\u093c \u0926\u0947\u0924\u0947 \u0939\u0948\u0902\u0964"},zh:{about:"\u300c\u5e7f\u5ea6\uff1a\u5e8f\u5217\u8bb0\u5fc6\u300d\u7ed9\u4f60\u770b\u4e00\u6bb5\u4e0d\u65ad\u53d8\u957f\u7684\u5e8f\u5217\uff0c\u6761\u76ee\u4e00\u4e2a\u63a5\u4e00\u4e2a\u5730\u4eae\u8d77\uff0c\u4f60\u7684\u4efb\u52a1\u662f\u6309\u5b8c\u5168\u76f8\u540c\u7684\u987a\u5e8f\u628a\u5b83\u56de\u653e\u51fa\u6765\u3002\u6bcf\u5f53\u4f60\u6b63\u786e\u590d\u73b0\u4e00\u8f6e\uff0c\u5e8f\u5217\u5c31\u518d\u52a0\u957f\u4e00\u6b65\uff0c\u4e8e\u662f\u6e38\u620f\u4f1a\u4e00\u76f4\u628a\u4f60\u903c\u5230\u4f60\u6240\u80fd\u8bb0\u4f4f\u7684\u6781\u9650\u3002",benefit:"\u5b83\u8bad\u7ec3\u5bf9\u6709\u5e8f\u4fe1\u606f\u7684\u77ed\u65f6\u8bb0\u5fc6\u548c\u5de5\u4f5c\u8bb0\u5fc6\uff0c\u5916\u52a0\u4f60\u767b\u8bb0\u6bcf\u4e2a\u6761\u76ee\u800c\u4e0d\u8d70\u795e\u6240\u9700\u8981\u7684\u4e13\u6ce8\u6ce8\u610f\u529b\u3002\u8bf4\u767d\u4e86\uff0c\u5b83\u5728\u62c9\u4f38\u4f60\u4e00\u6b21\u80fd\u5728\u8111\u4e2d\u4fdd\u6301\u591a\u5c11\u5185\u5bb9\u3001\u5e76\u628a\u5b83\u4eec\u7ef4\u6301\u5728\u6b63\u786e\u987a\u5e8f\u4e0a\u3002",history:"\u5b83\u6e90\u81ea\u8bb0\u5fc6\u5e7f\u5ea6\u4f20\u7edf\uff0c\u800c\u8fd9\u4e00\u4f20\u7edf\u59cb\u4e8e19\u4e16\u7eaa\u672b\u7684\u5b9e\u9a8c\u5fc3\u7406\u5b66\u2014\u2014\u5f53\u65f6\u7814\u7a76\u8005\u5f00\u59cb\u6d4b\u91cf\u4e00\u4e2a\u4eba\u80fd\u590d\u8ff0\u51fa\u6765\u7684\u6700\u957f\u5e8f\u5217\u3002\u7a7a\u95f4\u7684\u3001\u74f7\u7816\u4eae\u706f\u5f0f\u7684\u7248\u672c\uff0c\u901a\u8fc72010\u5e74\u4ee3\u7684\u5728\u7ebf\u57fa\u51c6\u6d4b\u8bd5\u4e3a\u5927\u4f17\u6240\u719f\u77e5\uff0c\u5b83\u4e5f\u547c\u5e94\u4e86\u90a3\u4e9b\u7ecf\u5178\u7684\u7535\u5b50\u8bb0\u5fc6\u73a9\u5177\u2014\u2014\u4f60\u8981\u7167\u642c\u4e00\u4e32\u8d8a\u6765\u8d8a\u957f\u7684\u706f\u5149\u548c\u58f0\u97f3\u3002",creator:"\u8fd9\u4e2a\u6e38\u620f\u7684\u786e\u5207\u5f62\u6001\u6ca1\u6709\u5355\u4e00\u53d1\u660e\u8005\u3002\u5e95\u5c42\u7684\u300c\u5373\u65f6\u987a\u5e8f\u56de\u5fc6\u300d\u4efb\u52a1\u901a\u5e38\u5f52\u529f\u4e8eJoseph Jacobs\uff0c\u4ed6\u57281887\u5e74\u6d4b\u91cf\u4e86\u6570\u5b57\u5e7f\u5ea6\uff1b\u89c6\u7a7a\u95f4\u7684\u5e8f\u5217\u5f62\u5f0f\u5219\u627f\u88ad\u81eaPhilip Corsi\u7684\u65b9\u5757\u6572\u51fb\u6d4b\u9a8c\uff081972\u5e74\uff09\u3002\u800c\u90a3\u79cd\u4e3a\u4eba\u719f\u77e5\u7684\u4eae\u706f\u74f7\u7816\u7248\u672c\uff0c\u662f\u7531Human Benchmark\u7b49\u5728\u7ebf\u5de5\u5177\u63a8\u5e7f\u5f00\u6765\u7684\uff0c\u5e76\u975e\u51fa\u81ea\u67d0\u4f4d\u5177\u540d\u4f5c\u8005\u3002",methods:"\u628a\u5e8f\u5217\u5207\u6210\u4e24\u4e09\u4e2a\u4e00\u7ec4\u7684\u5c0f\u5757\uff0c\u800c\u4e0d\u662f\u9010\u4e2a\u5b64\u7acb\u5730\u53bb\u80cc\uff0c\u5e76\u7ed9\u6bcf\u4e2a\u5c0f\u5757\u914d\u4e0a\u4e00\u6bb5\u5feb\u901f\u7684\u8282\u594f\u6216\u5c0f\u6545\u4e8b\uff0c\u8ba9\u5b83\u66f4\u9ecf\u5f97\u4f4f\u3002\u5728\u5b83\u64ad\u653e\u65f6\u9ed8\u9ed8\u590d\u8ff0\u8fd9\u4e00\u4e32\uff0c\u773c\u775b\u653e\u677e\u597d\u8ba9\u4f60\u628a\u6574\u4e2a\u68cb\u76d8\u5c3d\u6536\u773c\u5e95\uff0c\u56de\u653e\u65f6\u653e\u6162\u4e9b\uff0c\u522b\u56fe\u5feb\u800c\u6253\u4e71\u4e86\u81ea\u5df1\u7684\u987a\u5e8f\u3002",duration:"\u77ed\u800c\u9891\u7e41\u7684\u7ec3\u4e60\u80dc\u8fc7\u9a6c\u62c9\u677e\uff1a\u6bcf\u5929\u4e94\u5230\u5341\u5206\u949f\u3001\u4e00\u5468\u51e0\u6b21\uff0c\u5c31\u8db3\u591f\u4e86\u3002\u51c6\u786e\u7387\u5f00\u59cb\u4e0b\u6ed1\u65f6\u5c31\u505c\uff0c\u56e0\u4e3a\u5728\u4e25\u91cd\u75b2\u52b3\u4e0b\u786c\u6491\uff0c\u7ec3\u51fa\u6765\u7684\u591a\u534a\u662f\u632b\u8d25\u611f\u800c\u975e\u8bb0\u5fc6\u3002",research:"\u8bc1\u636e\u6700\u6709\u529b\u7684\u6070\u6070\u662f\u4f60\u80fd\u60f3\u5230\u7684\u90a3\u90e8\u5206\uff1a\u7ec3\u8fd9\u4e2a\uff0c\u4f60\u5c31\u4f1a\u5728\u8bb0\u8fd9\u7c7b\u5e8f\u5217\u4e0a\u660e\u663e\u53d8\u597d\u3002\u90a3\u4e9b\u66f4\u5927\u7684\u8bf4\u6cd5\u8981\u9760\u4e0d\u4f4f\u5f97\u591a\uff1b\u77e5\u540d\u7684\u5143\u5206\u6790\uff08Melby-Lerv\xe5g\u548cHulme\uff0c2016\uff09\u53d1\u73b0\uff0c\u8bb0\u5fc6\u5e7f\u5ea6\u548c\u5de5\u4f5c\u8bb0\u5fc6\u8bad\u7ec3\u5e76\u4e0d\u80fd\u53ef\u9760\u5730\u63d0\u9ad8\u4e00\u822c\u667a\u529b\uff0c\u4e5f\u4e0d\u4f1a\u4ea7\u751f\u5e7f\u6cdb\u7684\u73b0\u5b9e\u4e16\u754c\u8fc1\u79fb\uff0c\u800c\u51e0\u9879\u627f\u8bfa\u6709\u6b64\u7c7b\u6536\u76ca\u7684\u62db\u724c\u7814\u7a76\u4e5f\u672a\u80fd\u88ab\u91cd\u590d\uff0c\u6240\u4ee5\u5bf9\u4efb\u4f55\u7b3c\u7edf\u7684\u627f\u8bfa\u90fd\u8981\u4fdd\u6301\u8c28\u614e\u3002",rec:"\u523b\u610f\u8bad\u7ec3\u300c\u5206\u5757\u300d\u4e00\u4e24\u5468\uff0c\u7136\u540e\u53bb\u770b\u4f60\u7684\u5e7f\u5ea6\uff0c\u800c\u4e0d\u53ea\u662f\u53bb\u8ffd\u9010\u539f\u59cb\u56de\u5fc6\u4e0a\u7684\u9ad8\u5206\u3002",faq:[["\u8fd9\u80fd\u8ba9\u6211\u6574\u4f53\u53d8\u806a\u660e\u5417\uff1f","\u8001\u5b9e\u8bf4\uff0c\u4e0d\u80fd\uff0c\u5728\u4efb\u4f55\u5bbd\u6cdb\u610f\u4e49\u4e0a\u90fd\u4e0d\u80fd\u3002\u4f60\u4f1a\u5728\u8bb0\u5e8f\u5217\u4e0a\u660e\u663e\u53d8\u597d\uff0c\u8fd9\u672c\u8eab\u6709\u5b83\u7684\u4ef7\u503c\uff0c\u4f46\u8bc1\u636e\u5e76\u4e0d\u652f\u6301\u300c\u5b83\u80fd\u63d0\u9ad8\u667a\u5546\u6216\u8fc1\u79fb\u5230\u65e0\u5173\u65e5\u5e38\u4efb\u52a1\u300d\u8fd9\u7c7b\u8bf4\u6cd5\u3002"],["\u4e3a\u4ec0\u4e48\u6211\u5230\u67d0\u4e2a\u957f\u5ea6\u5c31\u649e\u5899\u4e86\uff1f","\u90a3\u662f\u4f60\u7684\u5de5\u4f5c\u8bb0\u5fc6\u5e7f\u5ea6\uff0c\u5b83\u5929\u751f\u6709\u9650\uff0c\u5e38\u5e38\u5728\u4f17\u6240\u5468\u77e5\u7684\u300c7\xb12\u300d\u8303\u56f4\u9644\u8fd1\u3002\u5206\u5757\u548c\u590d\u8ff0\u80fd\u628a\u5b83\u5f80\u4e0a\u63a8\u4e00\u70b9\uff0c\u4f46\u4eba\u4eba\u90fd\u4f1a\u78b0\u5230\u5929\u82b1\u677f\uff0c\u6240\u4ee5\u628a\u5b83\u5f53\u6210\u4e2a\u4eba\u57fa\u51c6\uff0c\u800c\u975e\u4e00\u79cd\u5931\u8d25\u3002"],["\u56de\u5fc6\u662f\u5feb\u4e00\u70b9\u597d\u8fd8\u662f\u51c6\u4e00\u70b9\u597d\uff1f","\u51c6\u4e00\u70b9\u3002\u53ea\u6709\u5f53\u4f60\u6beb\u65e0\u5dee\u9519\u5730\u590d\u73b0\u65f6\uff0c\u5e8f\u5217\u624d\u4f1a\u53d8\u957f\uff0c\u6240\u4ee5\u4e00\u6b21\u4ece\u5bb9\u3001\u6b63\u786e\u7684\u56de\u653e\uff0c\u6c38\u8fdc\u80dc\u8fc7\u53c8\u5feb\u53c8\u9a6c\u864e\u7684\u56de\u653e\uff1b\u800c\u56fe\u5feb\uff0c\u6b63\u662f\u4eba\u4eec\u6253\u65ad\u81ea\u5df1\u8fde\u80dc\u7eaa\u5f55\u6700\u5e38\u89c1\u7684\u5355\u4e00\u539f\u56e0\u3002"]],variants:"\u5e38\u89c1\u53d8\u5316\u5305\u62ec\u6b63\u5e8f\u5bf9\u5012\u5e8f\u56de\u5fc6\uff08\u590d\u73b0\u987a\u5e8f\uff0c\u6216\u53cd\u8fc7\u6765\uff09\u3001\u7528\u6570\u5b57\u6216\u5b57\u6bcd\u5e7f\u5ea6\u66ff\u4ee3\u74f7\u7816\u3001Corsi\u5f0f\u7a7a\u95f4\u65b9\u5757\u5e8f\u5217\uff0c\u4ee5\u53ca\u50cf\u7ecf\u5178\u7535\u5b50\u8bb0\u5fc6\u6e38\u620f\u90a3\u6837\u7684\u989c\u8272\u6216\u58f0\u97f3\u5e8f\u5217\u3002\u66f4\u96be\u7684\u6a21\u5f0f\u4f1a\u7f29\u77ed\u663e\u793a\u65f6\u95f4\uff0c\u6216\u5728\u300c\u5448\u73b0\u300d\u4e0e\u300c\u56de\u5fc6\u300d\u4e4b\u95f4\u52a0\u5165\u5e72\u6270\u6b65\u9aa4\u3002"}},"spatial-span":{ru:{about:"\u041d\u0430 \u043f\u043e\u043b\u0435 \u043f\u043e \u043e\u0447\u0435\u0440\u0435\u0434\u0438 \u0437\u0430\u0433\u043e\u0440\u0430\u044e\u0442\u0441\u044f \u044f\u0447\u0435\u0439\u043a\u0438, \u0430 \u0432\u0430\u0448\u0430 \u0437\u0430\u0434\u0430\u0447\u0430 \u2014 \u043f\u043e\u0432\u0442\u043e\u0440\u0438\u0442\u044c \u043f\u043e\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c \u0432 \u043e\u0431\u0440\u0430\u0442\u043d\u043e\u043c \u043f\u043e\u0440\u044f\u0434\u043a\u0435: \u0441\u043d\u0430\u0447\u0430\u043b\u0430 \u0442\u0430, \u0447\u0442\u043e \u0432\u0441\u043f\u044b\u0445\u043d\u0443\u043b\u0430 \u043f\u043e\u0441\u043b\u0435\u0434\u043d\u0435\u0439, \u0438 \u0442\u0430\u043a \u0434\u043e \u0441\u0430\u043c\u043e\u0439 \u043f\u0435\u0440\u0432\u043e\u0439. \u041f\u043e\u0441\u043a\u043e\u043b\u044c\u043a\u0443 \u043f\u0443\u0442\u044c \u043d\u0443\u0436\u043d\u043e \u0443\u0434\u0435\u0440\u0436\u0430\u0442\u044c \u0432 \u0433\u043e\u043b\u043e\u0432\u0435 \u0438 \u043f\u0440\u043e\u043a\u0440\u0443\u0442\u0438\u0442\u044c \u0437\u0430\u0434\u043e\u043c \u043d\u0430\u043f\u0435\u0440\u0451\u0434, \u043d\u0430\u0433\u0440\u0443\u0437\u043a\u0430 \u043d\u0430 \u0440\u0430\u0431\u043e\u0447\u0443\u044e \u043f\u0430\u043c\u044f\u0442\u044c \u0432\u044b\u0448\u0435, \u0447\u0435\u043c \u043f\u0440\u0438 \u043f\u0440\u043e\u0441\u0442\u043e\u043c \u043f\u043e\u0432\u0442\u043e\u0440\u0435 \u0432 \u0442\u043e\u043c \u0436\u0435 \u043f\u043e\u0440\u044f\u0434\u043a\u0435.",benefit:"\u0422\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442\u0441\u044f \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u043e-\u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u0430\u044f \u0440\u0430\u0431\u043e\u0447\u0430\u044f \u043f\u0430\u043c\u044f\u0442\u044c: \u0443\u0434\u0435\u0440\u0436\u0430\u043d\u0438\u0435 \u0446\u0435\u043f\u043e\u0447\u043a\u0438 \u043f\u043e\u0437\u0438\u0446\u0438\u0439 \u0438 \u043c\u044b\u0441\u043b\u0435\u043d\u043d\u0430\u044f \u0440\u0430\u0431\u043e\u0442\u0430 \u0441 \u043d\u0435\u0439, \u0430 \u043d\u0435 \u043f\u0440\u043e\u0441\u0442\u043e \u0445\u0440\u0430\u043d\u0435\u043d\u0438\u0435. \u0428\u0430\u0433 \u0440\u0430\u0437\u0432\u043e\u0440\u043e\u0442\u0430 \u043f\u043e\u0434\u043a\u043b\u044e\u0447\u0430\u0435\u0442 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u0438 \u0443\u043f\u0440\u0430\u0432\u043b\u044f\u044e\u0449\u0438\u0439 \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044c \u2014 \u0432\u0435\u0441\u044c \u043f\u0443\u0442\u044c \u043f\u0440\u0438\u0445\u043e\u0434\u0438\u0442\u0441\u044f \u0434\u0435\u0440\u0436\u0430\u0442\u044c \u0430\u043a\u0442\u0438\u0432\u043d\u044b\u043c, \u043e\u0434\u043d\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u043e \u043f\u0435\u0440\u0435\u0441\u0442\u0440\u0430\u0438\u0432\u0430\u044f \u0435\u0433\u043e \u0432 \u043e\u0431\u0440\u0430\u0442\u043d\u043e\u043c \u043d\u0430\u043f\u0440\u0430\u0432\u043b\u0435\u043d\u0438\u0438.",history:"\u0423\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u0435 \u0432\u044b\u0440\u043e\u0441\u043b\u043e \u0438\u0437 \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u0438 \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0433\u043e \u043e\u0431\u044a\u0451\u043c\u0430 \u043f\u0430\u043c\u044f\u0442\u0438, \u043d\u0430\u0447\u0430\u0432\u0448\u0435\u0439\u0441\u044f \u0441 \u0442\u0435\u0441\u0442\u0430 \u043f\u043e\u0441\u0442\u0443\u043a\u0438\u0432\u0430\u043d\u0438\u044f \u043f\u043e \u043a\u0443\u0431\u0438\u043a\u0430\u043c \u041a\u043e\u0440\u0441\u0438 \u0432 \u043a\u043b\u0438\u043d\u0438\u0447\u0435\u0441\u043a\u043e\u0439 \u043d\u0435\u0439\u0440\u043e\u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u0438, \u0433\u0434\u0435 \u043f\u0440\u043e\u0441\u0442\u0443\u043a\u0438\u0432\u0430\u043d\u0438\u0435 \u043a\u0443\u0431\u0438\u043a\u043e\u0432 \u043f\u043e \u043f\u043e\u0440\u044f\u0434\u043a\u0443 \u0441\u0442\u0430\u043b\u043e \u0441\u0442\u0430\u043d\u0434\u0430\u0440\u0442\u043d\u044b\u043c \u0441\u043f\u043e\u0441\u043e\u0431\u043e\u043c \u043e\u0446\u0435\u043d\u0438\u0442\u044c \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u0443\u044e \u043f\u0430\u043c\u044f\u0442\u044c. \u041e\u0431\u0440\u0430\u0442\u043d\u0430\u044f \u0432\u0435\u0440\u0441\u0438\u044f \u043f\u043e\u0432\u0442\u043e\u0440\u0438\u043b\u0430 \u043b\u043e\u0433\u0438\u043a\u0443 \u043e\u0431\u0440\u0430\u0442\u043d\u043e\u0433\u043e \u0446\u0438\u0444\u0440\u043e\u0432\u043e\u0433\u043e \u043e\u0431\u044a\u0451\u043c\u0430 \u2014 \u0440\u0430\u0437\u0432\u0435\u0440\u043d\u0443\u0442\u044c \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u0435\u0434\u0435\u043d\u0438\u0435, \u0447\u0442\u043e\u0431\u044b \u0441\u0438\u043b\u044c\u043d\u0435\u0435 \u043d\u0430\u0433\u0440\u0443\u0437\u0438\u0442\u044c \u043f\u0430\u043c\u044f\u0442\u044c, \u2014 \u0438 \u0441\u0435\u0433\u043e\u0434\u043d\u044f \u0440\u0435\u0432\u0435\u0440\u0441\u0438\u0432\u043d\u044b\u0439 \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0439 \u043e\u0431\u044a\u0451\u043c \u0432\u0445\u043e\u0434\u0438\u0442 \u0432 \u0442\u0435\u0441\u0442\u043e\u0432\u044b\u0435 \u0431\u0430\u0442\u0430\u0440\u0435\u0438 \u0432\u0440\u043e\u0434\u0435 \u0448\u043a\u0430\u043b\u044b \u043f\u0430\u043c\u044f\u0442\u0438 \u0412\u0435\u043a\u0441\u043b\u0435\u0440\u0430 \u0438 Spatial Span \u043e\u0442 Cambridge Cognition.",creator:"\u0415\u0434\u0438\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0433\u043e \u0430\u0432\u0442\u043e\u0440\u0430 \u0443 \u043e\u0431\u0440\u0430\u0442\u043d\u043e\u0433\u043e \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0433\u043e \u043e\u0431\u044a\u0451\u043c\u0430 \u043d\u0435\u0442. \u041f\u0440\u044f\u043c\u043e\u0439 \u0432\u0430\u0440\u0438\u0430\u043d\u0442 \u2014 \u0442\u0435\u0441\u0442 \u043f\u043e\u0441\u0442\u0443\u043a\u0438\u0432\u0430\u043d\u0438\u044f \u043f\u043e \u043a\u0443\u0431\u0438\u043a\u0430\u043c \u041a\u043e\u0440\u0441\u0438 \u2014 \u0440\u0430\u0437\u0440\u0430\u0431\u043e\u0442\u0430\u043b \u0424\u0438\u043b\u0438\u043f \u041a\u043e\u0440\u0441\u0438 \u0432 \u0434\u043e\u043a\u0442\u043e\u0440\u0441\u043a\u043e\u0439 \u0440\u0430\u0431\u043e\u0442\u0435 1972 \u0433\u043e\u0434\u0430 \u043f\u043e\u0434 \u0440\u0443\u043a\u043e\u0432\u043e\u0434\u0441\u0442\u0432\u043e\u043c \u0411\u0440\u0435\u043d\u0434\u044b \u041c\u0438\u043b\u043d\u0435\u0440 \u0432 \u0423\u043d\u0438\u0432\u0435\u0440\u0441\u0438\u0442\u0435\u0442\u0435 \u041c\u0430\u043a\u0433\u0438\u043b\u043b\u0430, \u043e\u043f\u0438\u0440\u0430\u044f\u0441\u044c \u043d\u0430 \u0435\u0451 \u0431\u043e\u043b\u0435\u0435 \u0440\u0430\u043d\u043d\u0438\u0435 \u0441\u043e\u043e\u0431\u0449\u0435\u043d\u0438\u044f \u043e\u043a\u043e\u043b\u043e 1971 \u0433\u043e\u0434\u0430; \u043e\u0431\u0440\u0430\u0442\u043d\u044b\u0439 \u0432\u0430\u0440\u0438\u0430\u043d\u0442 \u2014 \u044d\u0442\u043e \u0431\u043e\u043b\u0435\u0435 \u043f\u043e\u0437\u0434\u043d\u044f\u044f \u0430\u0434\u0430\u043f\u0442\u0430\u0446\u0438\u044f \u043d\u0430\u0443\u0447\u043d\u043e\u0433\u043e \u0441\u043e\u043e\u0431\u0449\u0435\u0441\u0442\u0432\u0430, \u0430 \u0440\u0435\u0432\u0435\u0440\u0441\u0438\u0432\u043d\u044b\u0439 \u0441\u0443\u0431\u0442\u0435\u0441\u0442 Spatial Span \u0434\u043e\u0431\u0430\u0432\u0438\u043b\u0438 \u0432 \u0448\u043a\u0430\u043b\u0443 \u043f\u0430\u043c\u044f\u0442\u0438 \u0412\u0435\u043a\u0441\u043b\u0435\u0440\u0430 (WMS-III) \u0432 1997 \u0433\u043e\u0434\u0443.",methods:"\u041d\u0435 \u0437\u0443\u0431\u0440\u0438\u0442\u0435 \u043e\u0442\u0434\u0435\u043b\u044c\u043d\u044b\u0435 \u0442\u043e\u0447\u043a\u0438 \u2014 \u0441\u043e\u0431\u0435\u0440\u0438\u0442\u0435 \u043f\u043e\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c \u0432 \u0444\u0438\u0433\u0443\u0440\u0443 \u0438\u043b\u0438 \u043b\u0438\u043d\u0438\u044e, \u043a\u043e\u0442\u043e\u0440\u0443\u044e \u0433\u043b\u0430\u0437 \u043c\u043e\u0436\u0435\u0442 \u043f\u0440\u043e\u0441\u043b\u0435\u0434\u0438\u0442\u044c, \u0430 \u0437\u0430\u0442\u0435\u043c \u043c\u044b\u0441\u043b\u0435\u043d\u043d\u043e \u043f\u0440\u043e\u0439\u0434\u0438\u0442\u0435 \u044d\u0442\u043e\u0442 \u043f\u0443\u0442\u044c \u0432 \u043e\u0431\u0440\u0430\u0442\u043d\u0443\u044e \u0441\u0442\u043e\u0440\u043e\u043d\u0443. \u041f\u043e\u043c\u043e\u0433\u0430\u0435\u0442 \u043f\u0440\u043e\u0433\u043e\u0432\u0430\u0440\u0438\u0432\u0430\u043d\u0438\u0435 \u043f\u0440\u043e \u0441\u0435\u0431\u044f \u0438\u043b\u0438 \u0443\u043a\u0430\u0437\u044b\u0432\u0430\u043d\u0438\u0435 \u043f\u043e \u043c\u0430\u0440\u0448\u0440\u0443\u0442\u0443, \u043f\u043e\u043a\u0430 \u043e\u043d \u043f\u043e\u044f\u0432\u043b\u044f\u0435\u0442\u0441\u044f; \u0434\u043b\u0438\u043d\u043d\u044b\u0435 \u0446\u0435\u043f\u043e\u0447\u043a\u0438 \u0440\u0430\u0437\u0431\u0438\u0432\u0430\u0439\u0442\u0435 \u043d\u0430 \u0434\u0432\u0430-\u0442\u0440\u0438 \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u0445 \u043e\u0442\u0440\u0435\u0437\u043a\u0430 \u0438 \u0440\u0430\u0437\u0432\u043e\u0440\u0430\u0447\u0438\u0432\u0430\u0439\u0442\u0435 \u043a\u0430\u0436\u0434\u044b\u0439. \u0414\u043b\u0438\u043d\u0443 \u043d\u0430\u0440\u0430\u0449\u0438\u0432\u0430\u0439\u0442\u0435 \u0442\u043e\u043b\u044c\u043a\u043e \u0442\u043e\u0433\u0434\u0430, \u043a\u043e\u0433\u0434\u0430 \u0443\u0432\u0435\u0440\u0435\u043d\u043d\u043e \u043f\u0440\u043e\u0445\u043e\u0434\u0438\u0442\u0435 \u0443\u0440\u043e\u0432\u0435\u043d\u044c, \u0438 \u043b\u0443\u0447\u0448\u0435 \u0437\u0430\u043c\u0435\u0434\u043b\u0438\u0442\u044c\u0441\u044f, \u0447\u0442\u043e\u0431\u044b \u0443\u0431\u0440\u0430\u0442\u044c \u0441\u043b\u0443\u0447\u0430\u0439\u043d\u044b\u0435 \u043f\u0440\u043e\u043c\u0430\u0445\u0438, \u0447\u0435\u043c \u0433\u043d\u0430\u0442\u044c \u043d\u0430 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c.",duration:"\u041a\u043e\u0440\u043e\u0442\u043a\u0438\u0435 \u0447\u0430\u0441\u0442\u044b\u0435 \u043f\u043e\u0434\u0445\u043e\u0434\u044b \u0432\u044b\u0438\u0433\u0440\u044b\u0432\u0430\u044e\u0442 \u0443 \u043c\u0430\u0440\u0430\u0444\u043e\u043d\u043e\u0432: \u043f\u044f\u0442\u0438-\u0434\u0435\u0441\u044f\u0442\u0438 \u043c\u0438\u043d\u0443\u0442 \u0432 \u0434\u0435\u043d\u044c \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0440\u0430\u0437 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e \u0432\u043f\u043e\u043b\u043d\u0435 \u0434\u043e\u0441\u0442\u0430\u0442\u043e\u0447\u043d\u043e. \u0417\u0430\u0434\u0430\u0447\u0438 \u043d\u0430 \u0440\u0430\u0431\u043e\u0447\u0443\u044e \u043f\u0430\u043c\u044f\u0442\u044c \u0431\u044b\u0441\u0442\u0440\u043e \u0443\u0442\u043e\u043c\u043b\u044f\u044e\u0442, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u043e\u0441\u0442\u0430\u043d\u0430\u0432\u043b\u0438\u0432\u0430\u0439\u0442\u0435\u0441\u044c, \u043a\u043e\u0433\u0434\u0430 \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u044c \u043d\u0430\u0447\u0438\u043d\u0430\u0435\u0442 \u043f\u0430\u0434\u0430\u0442\u044c, \u0430 \u043d\u0435 \u043f\u0440\u043e\u0434\u0430\u0432\u043b\u0438\u0432\u0430\u0439\u0442\u0435 \u0434\u0430\u043b\u044c\u0448\u0435.",research:"\u041d\u0430\u0434\u0451\u0436\u043d\u043e \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043d\u043e \u0443\u0437\u043a\u043e\u0435 \u0438 \u043e\u0436\u0438\u0434\u0430\u0435\u043c\u043e\u0435: \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u044f\u0441\u044c, \u0432\u044b \u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u0435\u0441\u044c \u043b\u0443\u0447\u0448\u0435 \u0438\u043c\u0435\u043d\u043d\u043e \u0432 \u044d\u0442\u043e\u043c \u2014 \u0440\u0430\u0441\u0442\u0451\u0442 \u043e\u0431\u044a\u0451\u043c \u0432 \u043e\u0431\u0440\u0430\u0442\u043d\u044b\u0445 \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0445 \u0437\u0430\u0434\u0430\u0447\u0430\u0445 \u0438 \u0438\u043c \u043f\u043e\u0434\u043e\u0431\u043d\u044b\u0445. \u0410 \u0432\u043e\u0442 \u043a\u0440\u0443\u043f\u043d\u044b\u0435 \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f \u043d\u0435 \u0432\u044b\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u044e\u0442 \u043f\u0440\u043e\u0432\u0435\u0440\u043a\u0438: \u0431\u043e\u043b\u044c\u0448\u0438\u0435 \u043c\u0435\u0442\u0430-\u0430\u043d\u0430\u043b\u0438\u0437\u044b (\u041c\u0435\u043b\u0431\u0438-\u041b\u0435\u0440\u0432\u043e\u0433 \u0438 \u043a\u043e\u043b\u043b\u0435\u0433\u0438, 2016) \u043f\u043e\u043a\u0430\u0437\u0430\u043b\u0438, \u0447\u0442\u043e \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0430 \u0440\u0430\u0431\u043e\u0447\u0435\u0439 \u043f\u0430\u043c\u044f\u0442\u0438 \u0434\u0430\u0451\u0442 \u043f\u0440\u0438\u0440\u043e\u0441\u0442 \u0442\u043e\u043b\u044c\u043a\u043e \u0432 \u0441\u0430\u043c\u0438\u0445 \u0437\u0430\u0434\u0430\u043d\u0438\u044f\u0445 \u0438 \u043d\u0435 \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0438\u0442\u0441\u044f \u043d\u0430 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0438\u043b\u0438 \u043f\u043e\u0432\u0441\u0435\u0434\u043d\u0435\u0432\u043d\u043e\u0435 \u043c\u044b\u0448\u043b\u0435\u043d\u0438\u0435, \u0442\u0430\u043a \u0447\u0442\u043e \u0437\u0430\u044f\u0432\u043b\u0435\u043d\u0438\u044f \u043f\u0440\u043e \u0440\u043e\u0441\u0442 IQ, \u043e\u0431\u0449\u0443\u044e \xab\u043f\u0440\u043e\u043a\u0430\u0447\u043a\u0443 \u043c\u043e\u0437\u0433\u0430\xbb \u0438\u043b\u0438 \u0437\u0430\u0449\u0438\u0442\u0443 \u043e\u0442 \u043a\u043e\u0433\u043d\u0438\u0442\u0438\u0432\u043d\u043e\u0433\u043e \u0441\u043f\u0430\u0434\u0430 \u043d\u0435 \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u044e\u0442\u0441\u044f. \u0421\u0447\u0438\u0442\u0430\u0439\u0442\u0435 \u044d\u0442\u043e \u0442\u043e\u0447\u0435\u0447\u043d\u043e\u0439 \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u043e\u0439 \u043a\u043e\u043d\u043a\u0440\u0435\u0442\u043d\u043e\u0433\u043e \u043d\u0430\u0432\u044b\u043a\u0430, \u0430 \u043d\u0435 \u0441\u043f\u043e\u0441\u043e\u0431\u043e\u043c \u043f\u043e\u0443\u043c\u043d\u0435\u0442\u044c.",rec:"\u0414\u043e\u0431\u0438\u0432\u0430\u0439\u0442\u0435\u0441\u044c \u0447\u0438\u0441\u0442\u044b\u0445 \u0440\u0430\u0437\u0432\u043e\u0440\u043e\u0442\u043e\u0432 \u043d\u0430 \u0442\u043e\u0439 \u0434\u043b\u0438\u043d\u0435, \u043a\u043e\u0442\u043e\u0440\u0443\u044e \u0440\u0435\u0430\u043b\u044c\u043d\u043e \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0435\u0442\u0435, \u0438 \u043f\u043e\u0434\u043d\u0438\u043c\u0430\u0439\u0442\u0435 \u0441\u043b\u043e\u0436\u043d\u043e\u0441\u0442\u044c \u043b\u0438\u0448\u044c \u0442\u043e\u0433\u0434\u0430, \u043a\u043e\u0433\u0434\u0430 \u044d\u0442\u0430 \u0434\u043b\u0438\u043d\u0430 \u0434\u0430\u0451\u0442\u0441\u044f \u043b\u0435\u0433\u043a\u043e.",faq:[["\u041f\u043e\u0447\u0435\u043c\u0443 \u043e\u0431\u0440\u0430\u0442\u043d\u0430\u044f \u0432\u0435\u0440\u0441\u0438\u044f \u0442\u0440\u0443\u0434\u043d\u0435\u0435 \u043f\u0440\u044f\u043c\u043e\u0439?","\u041f\u043e\u0432\u0442\u043e\u0440 \u043f\u0443\u0442\u0438 \u0432 \u043f\u0440\u044f\u043c\u043e\u043c \u043f\u043e\u0440\u044f\u0434\u043a\u0435 \u043f\u0440\u043e\u0432\u0435\u0440\u044f\u0435\u0442 \u0432 \u043e\u0441\u043d\u043e\u0432\u043d\u043e\u043c \u0445\u0440\u0430\u043d\u0435\u043d\u0438\u0435, \u0430 \u0440\u0430\u0437\u0432\u043e\u0440\u043e\u0442 \u0437\u0430\u0441\u0442\u0430\u0432\u043b\u044f\u0435\u0442 \u0434\u0435\u0440\u0436\u0430\u0442\u044c \u0432\u0441\u044e \u0446\u0435\u043f\u043e\u0447\u043a\u0443 \u0430\u043a\u0442\u0438\u0432\u043d\u043e\u0439 \u0438 \u043f\u0435\u0440\u0435\u0441\u0442\u0440\u0430\u0438\u0432\u0430\u0442\u044c \u0435\u0451 \u0432 \u043e\u0431\u0440\u0430\u0442\u043d\u0443\u044e \u0441\u0442\u043e\u0440\u043e\u043d\u0443 \u2014 \u044d\u0442\u043e \u0434\u043e\u0431\u0430\u0432\u043b\u044f\u0435\u0442 \u043a \u043f\u0430\u043c\u044f\u0442\u0438 \u0435\u0449\u0451 \u043e\u0434\u0438\u043d \u0448\u0430\u0433 \u043c\u0430\u043d\u0438\u043f\u0443\u043b\u044f\u0446\u0438\u0438."],["\u0421\u0442\u0430\u043d\u0443 \u043b\u0438 \u044f \u0443\u043c\u043d\u0435\u0435 \u0438\u043b\u0438 \u043f\u043e\u0432\u044b\u0448\u0443 \u043b\u0438 IQ?","\u041d\u0435\u0442. \u0414\u0430\u043d\u043d\u044b\u0435 \u043f\u043e\u043a\u0430\u0437\u044b\u0432\u0430\u044e\u0442, \u0447\u0442\u043e \u0432\u044b \u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u0435\u0441\u044c \u043b\u0443\u0447\u0448\u0435 \u0432 \u0441\u0430\u043c\u043e\u043c \u0437\u0430\u0434\u0430\u043d\u0438\u0438 \u0438 \u0431\u043b\u0438\u0437\u043a\u0438\u0445 \u043a \u043d\u0435\u043c\u0443, \u043d\u043e \u044d\u0442\u043e\u0442 \u043f\u0440\u0438\u0440\u043e\u0441\u0442 \u043d\u0435 \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0438\u0442\u0441\u044f \u043d\u0430 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0438\u043b\u0438 \u043c\u044b\u0448\u043b\u0435\u043d\u0438\u0435 \u0432 \u0436\u0438\u0437\u043d\u0438, \u0442\u0430\u043a \u0447\u0442\u043e \u044d\u0442\u043e \u0441\u043a\u043e\u0440\u0435\u0435 \u0442\u043e\u0447\u0435\u0447\u043d\u0430\u044f \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u0430, \u0430 \u043d\u0435 \u0430\u043f\u0433\u0440\u0435\u0439\u0434 \u043c\u043e\u0437\u0433\u0430."],["\u0427\u0435\u043c \u044d\u0442\u043e \u043e\u0442\u043b\u0438\u0447\u0430\u0435\u0442\u0441\u044f \u043e\u0442 \u043e\u0431\u0440\u0430\u0442\u043d\u043e\u0433\u043e \u0446\u0438\u0444\u0440\u043e\u0432\u043e\u0433\u043e \u043e\u0431\u044a\u0451\u043c\u0430?","\u0418\u0434\u0435\u044f \u0442\u0430 \u0436\u0435, \u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b \u0440\u0430\u0437\u043d\u044b\u0439: \u0432 \u0446\u0438\u0444\u0440\u043e\u0432\u043e\u043c \u043e\u0431\u044a\u0451\u043c\u0435 \u0440\u0430\u0437\u0432\u043e\u0440\u0430\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044f \u0440\u044f\u0434 \u0447\u0438\u0441\u0435\u043b \u0438 \u0440\u0430\u0431\u043e\u0442\u0430\u0435\u0442 \u0441\u043b\u043e\u0432\u0435\u0441\u043d\u0430\u044f \u043f\u0430\u043c\u044f\u0442\u044c, \u0430 \u0432 \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u043c \u0440\u0430\u0437\u0432\u043e\u0440\u0430\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044f \u0446\u0435\u043f\u043e\u0447\u043a\u0430 \u043f\u043e\u0437\u0438\u0446\u0438\u0439 \u0438 \u0440\u0430\u0431\u043e\u0442\u0430\u0435\u0442 \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u043e-\u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u0430\u044f \u043f\u0430\u043c\u044f\u0442\u044c."]],variants:"\u041f\u0440\u044f\u043c\u043e\u0439 \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0439 \u043e\u0431\u044a\u0451\u043c (\u043f\u043e\u0432\u0442\u043e\u0440 \u0432 \u0442\u043e\u043c \u0436\u0435 \u043f\u043e\u0440\u044f\u0434\u043a\u0435) \u2014 \u0431\u043e\u043b\u0435\u0435 \u043b\u0451\u0433\u043a\u0430\u044f \u0431\u0430\u0437\u043e\u0432\u0430\u044f \u0432\u0435\u0440\u0441\u0438\u044f; \u043a\u043b\u0430\u0441\u0441\u0438\u0447\u0435\u0441\u043a\u0430\u044f \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043a\u0430\u044f \u0444\u043e\u0440\u043c\u0430 \u2014 \u0442\u0435\u0441\u0442 \u043f\u043e\u0441\u0442\u0443\u043a\u0438\u0432\u0430\u043d\u0438\u044f \u043f\u043e \u043a\u0443\u0431\u0438\u043a\u0430\u043c \u041a\u043e\u0440\u0441\u0438 \u0441 \u0434\u0435\u0432\u044f\u0442\u044c\u044e \u043a\u0443\u0431\u0438\u043a\u0430\u043c\u0438. \u0412\u0430\u0440\u0438\u0430\u043d\u0442\u044b \u043c\u0435\u043d\u044f\u044e\u0442 \u0440\u0430\u0437\u043c\u0435\u0440 \u043f\u043e\u043b\u044f, \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u043f\u043e\u043a\u0430\u0437\u0430 \u0438 \u0434\u043b\u0438\u043d\u0443 \u043f\u0443\u0442\u0438, \u0430 \u0441\u043b\u043e\u0432\u0435\u0441\u043d\u044b\u0435 \u0440\u043e\u0434\u0441\u0442\u0432\u0435\u043d\u043d\u0438\u043a\u0438 \u0432\u0440\u043e\u0434\u0435 \u043e\u0431\u0440\u0430\u0442\u043d\u043e\u0433\u043e \u0446\u0438\u0444\u0440\u043e\u0432\u043e\u0433\u043e \u043e\u0431\u044a\u0451\u043c\u0430 \u043f\u0440\u0438\u043c\u0435\u043d\u044f\u044e\u0442 \u0442\u0443 \u0436\u0435 \u0438\u0434\u0435\u044e \u043e\u0431\u0440\u0430\u0442\u043d\u043e\u0433\u043e \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u0435\u0434\u0435\u043d\u0438\u044f \u043a \u0447\u0438\u0441\u043b\u0430\u043c \u0432\u043c\u0435\u0441\u0442\u043e \u043f\u043e\u0437\u0438\u0446\u0438\u0439."},en:{about:"A grid of pads lights up one after another, and your job is to repeat the sequence by tapping the pads in reverse order \u2014 last one first, back to the start. Because you have to hold the path in mind and run it backwards, it leans harder on working memory than simply echoing the order you saw.",benefit:"It trains visuospatial working memory: holding a sequence of locations in mind and mentally manipulating it rather than just storing it. The reversal step also pulls in attention and executive control, since you have to keep the whole path active while rebuilding it in the opposite direction.",history:"It grows out of the spatial-span tradition that began with the Corsi block-tapping task in clinical neuropsychology, where tapping cubes in order became a standard way to gauge spatial memory. The backward version followed the same logic as backward digit span \u2014 reverse the recall to load memory more heavily \u2014 and reversed spatial span is now offered in test batteries like the Wechsler Memory Scale and Cambridge Cognition's Spatial Span.",creator:"There is no single inventor of the backward spatial span. The forward task \u2014 the Corsi block-tapping test \u2014 was developed by Philip Corsi in his 1972 doctoral work under Brenda Milner at McGill, building on her earlier reports around 1971; the backward variant is a later adaptation by the wider research community, and a reversed Spatial Span subtest was added to the Wechsler Memory Scale (WMS-III) in 1997.",methods:"Don't try to memorise raw dots \u2014 turn the sequence into a shape or a path your eye can trace, then mentally walk that path backwards. Subvocalising or pointing along the route as it appears helps; chunk longer sequences into two or three smaller segments and reverse each. Push the length up only when you're clearing a level comfortably, and slow down to cut careless taps rather than racing.",duration:"Short, frequent sessions beat marathons: five to ten minutes a day, a handful of days a week, is plenty. Working memory tasks fatigue quickly, so stop when accuracy starts sliding rather than grinding on.",research:"What's solid is narrow and unsurprising \u2014 practise this and you get better at this, improving your span on backward spatial tasks and similar ones. The bigger claims are where it falls apart: large meta-analyses (Melby-Lerv\xe5g and colleagues, 2016) found that working-memory training produces task-specific gains that do not generalise to intelligence or everyday cognition, so promises that it raises IQ, boosts general 'brain power', or wards off cognitive decline are not supported. Treat it as a focused workout for a specific skill, not a shortcut to being smarter.",rec:"Chase clean reversals at a length you can actually hold, and bump the difficulty up only once that length feels easy.",faq:[["Why is the backward version harder than the forward one?","Repeating a path forward mostly tests storage, but reversing it forces you to hold the whole sequence active and rebuild it in the opposite direction, which adds an extra manipulation step on top of memory."],["Will this make me smarter or raise my IQ?","No. The evidence shows you get better at the task itself and close relatives, but those gains don't carry over to intelligence or real-world thinking, so it's best seen as targeted practice, not a brain upgrade."],["How is this different from backward digit span?","Same idea, different material: digit span reverses a string of numbers and leans on verbal memory, while spatial span reverses a sequence of locations and leans on visuospatial memory."]],variants:"Forward spatial span (repeat in the same order) is the easier baseline; the classic physical form is the Corsi block-tapping test with nine cubes. Variants tweak grid size, sequence speed, and how long the path is, and verbal cousins like backward digit span apply the same reverse-recall idea to numbers instead of locations."},es:{about:"Una cuadr\xedcula de paneles se ilumina uno tras otro, y tu tarea es repetir la secuencia tocando los paneles en orden inverso: primero el \xfaltimo, hasta volver al principio. Como tienes que retener el trayecto en la mente y recorrerlo al rev\xe9s, exige m\xe1s a la memoria de trabajo que simplemente repetir el orden que viste.",benefit:"Entrena la memoria de trabajo visoespacial: retener en la mente una secuencia de ubicaciones y manipularla mentalmente en lugar de solo almacenarla. El paso de inversi\xf3n tambi\xe9n pone en juego la atenci\xf3n y el control ejecutivo, ya que tienes que mantener activo todo el trayecto mientras lo reconstruyes en la direcci\xf3n contraria.",history:"Surge de la tradici\xf3n de la amplitud espacial que empez\xf3 con la tarea de golpeteo de bloques de Corsi en la neuropsicolog\xeda cl\xednica, donde tocar cubos en orden se convirti\xf3 en una forma est\xe1ndar de medir la memoria espacial. La versi\xf3n hacia atr\xe1s sigui\xf3 la misma l\xf3gica que la amplitud de d\xedgitos inversa \u2014invertir el recuerdo para exigir m\xe1s a la memoria\u2014 y la amplitud espacial invertida hoy se ofrece en bater\xedas de pruebas como la Escala de Memoria de Wechsler y la Spatial Span de Cambridge Cognition.",creator:"No hay un \xfanico inventor de la amplitud espacial hacia atr\xe1s. La tarea hacia delante \u2014la prueba de golpeteo de bloques de Corsi\u2014 fue desarrollada por Philip Corsi en su trabajo doctoral de 1972 bajo Brenda Milner en McGill, partiendo de los informes previos de ella en torno a 1971; la variante hacia atr\xe1s es una adaptaci\xf3n posterior de la comunidad investigadora en general, y un subtest de Amplitud Espacial invertida se a\xf1adi\xf3 a la Escala de Memoria de Wechsler (WMS-III) en 1997.",methods:"No intentes memorizar puntos sueltos: convierte la secuencia en una forma o un trayecto que tu ojo pueda trazar, y luego recorre mentalmente ese trayecto hacia atr\xe1s. Subvocalizar o se\xf1alar a lo largo de la ruta a medida que aparece ayuda; agrupa las secuencias largas en dos o tres segmentos m\xe1s peque\xf1os e invierte cada uno. Sube la longitud solo cuando superes un nivel con comodidad, y baja el ritmo para recortar los toques descuidados en lugar de correr.",duration:"Las sesiones cortas y frecuentes ganan a los maratones: de cinco a diez minutos al d\xeda, un pu\xf1ado de d\xedas por semana, es de sobra. Las tareas de memoria de trabajo fatigan r\xe1pido, as\xed que para cuando la precisi\xf3n empiece a caer en lugar de seguir machacando.",research:"Lo s\xf3lido es estrecho y poco sorprendente: practica esto y mejoras en esto, aumentando tu amplitud en tareas espaciales hacia atr\xe1s y similares. Las afirmaciones m\xe1s grandes son donde se viene abajo: grandes metaan\xe1lisis (Melby-Lerv\xe5g y colaboradores, 2016) hallaron que el entrenamiento de la memoria de trabajo produce mejoras espec\xedficas de la tarea que no se generalizan a la inteligencia ni a la cognici\xf3n cotidiana, as\xed que las promesas de que eleva el CI, aumenta la 'potencia cerebral' general o frena el deterioro cognitivo no est\xe1n respaldadas. T\xf3malo como un ejercicio enfocado para una habilidad concreta, no como un atajo para ser m\xe1s inteligente.",rec:"Persigue inversiones limpias en una longitud que realmente puedas retener, y sube la dificultad solo cuando esa longitud te resulte f\xe1cil.",faq:[["\xbfPor qu\xe9 la versi\xf3n hacia atr\xe1s es m\xe1s dif\xedcil que la de hacia delante?","Repetir un trayecto hacia delante pone a prueba sobre todo el almacenamiento, pero invertirlo te obliga a mantener activa toda la secuencia y a reconstruirla en la direcci\xf3n contraria, lo que a\xf1ade un paso extra de manipulaci\xf3n encima de la memoria."],["\xbfEsto me har\xe1 m\xe1s inteligente o subir\xe1 mi CI?","No. La evidencia muestra que mejoras en la propia tarea y en parientes cercanos, pero esas mejoras no se trasladan a la inteligencia ni al pensamiento del mundo real, as\xed que es mejor verlo como pr\xe1ctica dirigida y no como una mejora del cerebro."],["\xbfEn qu\xe9 se diferencia de la amplitud de d\xedgitos hacia atr\xe1s?","Misma idea, distinto material: la amplitud de d\xedgitos invierte una cadena de n\xfameros y se apoya en la memoria verbal, mientras que la amplitud espacial invierte una secuencia de ubicaciones y se apoya en la memoria visoespacial."]],variants:"La amplitud espacial hacia delante (repetir en el mismo orden) es la base m\xe1s f\xe1cil; la forma f\xedsica cl\xe1sica es la prueba de golpeteo de bloques de Corsi con nueve cubos. Las variantes ajustan el tama\xf1o de la cuadr\xedcula, la velocidad de la secuencia y la longitud del trayecto, y parientes verbales como la amplitud de d\xedgitos hacia atr\xe1s aplican la misma idea de recuerdo inverso a n\xfameros en lugar de ubicaciones."},de:{about:"Ein Raster aus Feldern leuchtet eines nach dem anderen auf, und deine Aufgabe ist es, die Abfolge zu wiederholen, indem du die Felder in umgekehrter Reihenfolge antippst \u2013 das letzte zuerst, zur\xfcck bis zum Anfang. Weil du den Pfad im Kopf behalten und r\xfcckw\xe4rts durchlaufen musst, beansprucht das das Arbeitsged\xe4chtnis st\xe4rker, als die gesehene Reihenfolge blo\xdf nachzuahmen.",benefit:"Es trainiert das visuell-r\xe4umliche Arbeitsged\xe4chtnis: eine Folge von Orten im Kopf zu behalten und sie geistig zu bearbeiten, statt sie nur zu speichern. Der Umkehrschritt zieht zus\xe4tzlich Aufmerksamkeit und exekutive Kontrolle hinzu, da du den gesamten Pfad aktiv halten musst, w\xe4hrend du ihn in der Gegenrichtung neu aufbaust.",history:"Es entstammt der Tradition der r\xe4umlichen Merkspanne, die mit der Corsi-Block-Tapping-Aufgabe in der klinischen Neuropsychologie begann, wo das Antippen von W\xfcrfeln in Reihenfolge zu einem Standardweg wurde, das r\xe4umliche Ged\xe4chtnis zu erfassen. Die R\xfcckw\xe4rtsversion folgte derselben Logik wie die r\xfcckw\xe4rts gerichtete Zahlenspanne \u2013 die Wiedergabe umzukehren, um das Ged\xe4chtnis st\xe4rker zu belasten \u2013 und die umgekehrte r\xe4umliche Merkspanne wird heute in Testbatterien wie der Wechsler Memory Scale und dem Spatial Span von Cambridge Cognition angeboten.",creator:"Es gibt keinen einzelnen Erfinder der r\xfcckw\xe4rts gerichteten r\xe4umlichen Merkspanne. Die Vorw\xe4rtsaufgabe \u2013 der Corsi-Block-Tapping-Test \u2013 wurde von Philip Corsi in seiner Doktorarbeit von 1972 unter Brenda Milner an der McGill University entwickelt, aufbauend auf ihren fr\xfcheren Berichten um 1971; die R\xfcckw\xe4rtsvariante ist eine sp\xe4tere Anpassung durch die breitere Forschungsgemeinschaft, und ein umgekehrter Spatial-Span-Untertest wurde 1997 zur Wechsler Memory Scale (WMS-III) hinzugef\xfcgt.",methods:"Versuche nicht, rohe Punkte auswendig zu lernen \u2013 verwandle die Abfolge in eine Form oder einen Pfad, den dein Blick nachzeichnen kann, und durchwandere diesen Pfad dann gedanklich r\xfcckw\xe4rts. Den Weg beim Erscheinen still mitzusprechen oder mitzuzeigen, hilft; fasse l\xe4ngere Abfolgen in zwei oder drei kleinere Abschnitte zusammen und kehre jeden einzeln um. Erh\xf6he die L\xe4nge erst, wenn du eine Stufe komfortabel meisterst, und verlangsame lieber, um unbedachte Ber\xfchrungen zu vermeiden, statt zu rasen.",duration:"Kurze, h\xe4ufige Einheiten schlagen Marathons: f\xfcnf bis zehn Minuten am Tag, an einer Handvoll Tage pro Woche, reichen v\xf6llig. Arbeitsged\xe4chtnisaufgaben erm\xfcden schnell, also h\xf6re auf, sobald die Genauigkeit nachl\xe4sst, statt weiterzumachen.",research:"Was solide ist, ist eng begrenzt und wenig \xfcberraschend \u2013 wenn du dies \xfcbst, wirst du darin besser und steigerst deine Spanne bei r\xfcckw\xe4rts gerichteten r\xe4umlichen Aufgaben und \xe4hnlichen. An den gr\xf6\xdferen Behauptungen scheitert es: Gro\xdfe Metaanalysen (Melby-Lerv\xe5g und Kollegen, 2016) fanden, dass Arbeitsged\xe4chtnistraining aufgabenspezifische Zugewinne erzeugt, die sich nicht auf Intelligenz oder allt\xe4gliche Kognition verallgemeinern \u2013 Versprechen, es steigere den IQ, kurbele die allgemeine 'Geisteskraft' an oder wehre kognitiven Abbau ab, sind also nicht belegt. Behandle es als gezieltes Training f\xfcr eine bestimmte F\xe4higkeit, nicht als Abk\xfcrzung zu mehr Klugheit.",rec:"Strebe saubere Umkehrungen bei einer L\xe4nge an, die du tats\xe4chlich halten kannst, und erh\xf6he die Schwierigkeit erst, wenn sich diese L\xe4nge leicht anf\xfchlt.",faq:[["Warum ist die R\xfcckw\xe4rtsversion schwerer als die Vorw\xe4rtsversion?","Einen Pfad vorw\xe4rts zu wiederholen pr\xfcft vor allem das Speichern, doch ihn umzukehren zwingt dich, die gesamte Abfolge aktiv zu halten und sie in der Gegenrichtung neu aufzubauen, was zus\xe4tzlich zum Ged\xe4chtnis einen Bearbeitungsschritt hinzuf\xfcgt."],["Macht mich das kl\xfcger oder erh\xf6ht es meinen IQ?","Nein. Die Belege zeigen, dass du in der Aufgabe selbst und in nahen Verwandten besser wirst, aber diese Zugewinne \xfcbertragen sich nicht auf die Intelligenz oder das Denken im Alltag \u2013 man sieht es also am besten als gezielte \xdcbung, nicht als Upgrade f\xfcrs Gehirn."],["Wie unterscheidet sich das von der r\xfcckw\xe4rts gerichteten Zahlenspanne?","Gleiche Idee, anderes Material: Die Zahlenspanne kehrt eine Ziffernfolge um und st\xfctzt sich auf das verbale Ged\xe4chtnis, w\xe4hrend die r\xe4umliche Merkspanne eine Folge von Orten umkehrt und sich auf das visuell-r\xe4umliche Ged\xe4chtnis st\xfctzt."]],variants:"Die vorw\xe4rts gerichtete r\xe4umliche Merkspanne (Wiederholung in derselben Reihenfolge) ist die leichtere Ausgangsform; die klassische physische Form ist der Corsi-Block-Tapping-Test mit neun W\xfcrfeln. Varianten ver\xe4ndern Rastergr\xf6\xdfe, Abfolgegeschwindigkeit und Pfadl\xe4nge, und verbale Verwandte wie die r\xfcckw\xe4rts gerichtete Zahlenspanne \xfcbertragen dieselbe Idee der R\xfcckw\xe4rtswiedergabe auf Zahlen statt auf Orte."},pt:{about:"Uma grade de bot\xf5es acende um ap\xf3s o outro, e a sua tarefa \xe9 repetir a sequ\xeancia tocando nos bot\xf5es em ordem inversa \u2014 do \xfaltimo para o primeiro, de volta ao in\xedcio. Como voc\xea precisa reter o trajeto na cabe\xe7a e percorr\xea-lo de tr\xe1s para frente, isso exige mais da mem\xf3ria de trabalho do que simplesmente repetir a ordem que voc\xea viu.",benefit:"Ele treina a mem\xf3ria de trabalho visuoespacial: reter uma sequ\xeancia de posi\xe7\xf5es na mente e manipul\xe1-la mentalmente, em vez de apenas armazen\xe1-la. O passo de invers\xe3o tamb\xe9m recruta aten\xe7\xe3o e controle executivo, j\xe1 que voc\xea tem de manter todo o trajeto ativo enquanto o reconstr\xf3i na dire\xe7\xe3o oposta.",history:"Nasce da tradi\xe7\xe3o do span espacial, que come\xe7ou com a tarefa de toque de blocos de Corsi na neuropsicologia cl\xednica, em que tocar os cubos em ordem virou uma forma padr\xe3o de medir a mem\xf3ria espacial. A vers\xe3o invertida seguiu a mesma l\xf3gica do span de d\xedgitos invertido \u2014 reverter a recorda\xe7\xe3o para exigir mais da mem\xf3ria \u2014 e o span espacial reverso \xe9 hoje oferecido em baterias de testes como a Escala de Mem\xf3ria de Wechsler e o Spatial Span da Cambridge Cognition.",creator:"N\xe3o h\xe1 um \xfanico inventor do span espacial invertido. A tarefa direta \u2014 o teste de toque de blocos de Corsi \u2014 foi desenvolvida por Philip Corsi em seu trabalho de doutorado de 1972 sob orienta\xe7\xe3o de Brenda Milner na McGill, com base em relatos anteriores dela por volta de 1971; a variante invertida \xe9 uma adapta\xe7\xe3o posterior da comunidade de pesquisa mais ampla, e um subteste de Spatial Span reverso foi acrescentado \xe0 Escala de Mem\xf3ria de Wechsler (WMS-III) em 1997.",methods:"N\xe3o tente memorizar pontos soltos \u2014 transforme a sequ\xeancia numa forma ou num trajeto que o seu olho consiga seguir e ent\xe3o percorra mentalmente esse trajeto de tr\xe1s para frente. Subvocalizar ou apontar ao longo do percurso enquanto ele aparece ajuda; agrupe sequ\xeancias mais longas em dois ou tr\xeas segmentos menores e inverta cada um. S\xf3 aumente o comprimento quando estiver passando de um n\xedvel com tranquilidade, e desacelere para cortar toques descuidados, em vez de correr.",duration:"Sess\xf5es curtas e frequentes vencem as maratonas: de cinco a dez minutos por dia, em alguns dias da semana, j\xe1 bastam. Tarefas de mem\xf3ria de trabalho cansam r\xe1pido, ent\xe3o pare quando a precis\xe3o come\xe7ar a cair, em vez de insistir.",research:"O que \xe9 s\xf3lido \xe9 estreito e pouco surpreendente \u2014 pratique isto e voc\xea fica melhor nisto, aumentando o seu span em tarefas espaciais invertidas e parecidas. As alega\xe7\xf5es maiores \xe9 que desabam: grandes meta-an\xe1lises (Melby-Lerv\xe5g e colegas, 2016) constataram que o treino de mem\xf3ria de trabalho produz ganhos espec\xedficos da tarefa que n\xe3o se generalizam para a intelig\xeancia ou a cogni\xe7\xe3o do dia a dia, ent\xe3o promessas de que ele aumenta o QI, turbina a 'capacidade cerebral' geral ou afasta o decl\xednio cognitivo n\xe3o t\xeam respaldo. Encare-o como um treino focado de uma habilidade espec\xedfica, n\xe3o como atalho para ficar mais inteligente.",rec:"Busque invers\xf5es limpas num comprimento que voc\xea realmente consiga reter, e s\xf3 aumente a dificuldade quando esse comprimento ficar f\xe1cil.",faq:[["Por que a vers\xe3o invertida \xe9 mais dif\xedcil que a direta?","Repetir um trajeto para frente testa sobretudo o armazenamento, mas invert\xea-lo obriga voc\xea a manter toda a sequ\xeancia ativa e a reconstru\xed-la na dire\xe7\xe3o oposta, o que acrescenta um passo extra de manipula\xe7\xe3o por cima da mem\xf3ria."],["Isso vai me deixar mais inteligente ou aumentar o meu QI?","N\xe3o. As evid\xeancias mostram que voc\xea fica melhor na pr\xf3pria tarefa e em parentes pr\xf3ximos, mas esses ganhos n\xe3o se transferem para a intelig\xeancia ou o pensamento do mundo real, ent\xe3o \xe9 melhor v\xea-lo como pr\xe1tica direcionada, n\xe3o como um upgrade cerebral."],["Como isso difere do span de d\xedgitos invertido?","Mesma ideia, material diferente: o span de d\xedgitos inverte uma cadeia de n\xfameros e se apoia na mem\xf3ria verbal, enquanto o span espacial inverte uma sequ\xeancia de posi\xe7\xf5es e se apoia na mem\xf3ria visuoespacial."]],variants:"O span espacial direto (repetir na mesma ordem) \xe9 a base mais f\xe1cil; a forma f\xedsica cl\xe1ssica \xe9 o teste de toque de blocos de Corsi com nove cubos. As variantes mexem no tamanho da grade, na velocidade da sequ\xeancia e na extens\xe3o do trajeto, e primos verbais como o span de d\xedgitos invertido aplicam a mesma ideia de recorda\xe7\xe3o reversa a n\xfameros em vez de posi\xe7\xf5es."},hi:{about:"\u092a\u0948\u0921\u094d\u0938 \u0915\u093e \u090f\u0915 \u0917\u094d\u0930\u093f\u0921 \u090f\u0915-\u090f\u0915 \u0915\u0930\u0915\u0947 \u091c\u0932\u0924\u093e \u0939\u0948, \u0914\u0930 \u0906\u092a\u0915\u093e \u0915\u093e\u092e \u0939\u0948 \u0909\u0938 \u0915\u094d\u0930\u092e \u0915\u094b \u0909\u0932\u094d\u091f\u093e \u0926\u094b\u0939\u0930\u093e\u0928\u093e \u2014 \u0906\u0916\u093c\u093f\u0930\u0940 \u092a\u0948\u0921 \u092a\u0939\u0932\u0947, \u0914\u0930 \u0935\u093e\u092a\u0938 \u0936\u0941\u0930\u0941\u0906\u0924 \u0924\u0915\u0964 \u091a\u0942\u0901\u0915\u093f \u0906\u092a\u0915\u094b \u092a\u0942\u0930\u0947 \u0930\u093e\u0938\u094d\u0924\u0947 \u0915\u094b \u092e\u0928 \u092e\u0947\u0902 \u0925\u093e\u092e\u0915\u0930 \u0909\u0938\u0947 \u0909\u0932\u094d\u091f\u093e \u091a\u0932\u093e\u0928\u093e \u092a\u0921\u093c\u0924\u093e \u0939\u0948, \u092f\u0939 \u092c\u0938 \u0926\u0947\u0916\u0947 \u0939\u0941\u090f \u0915\u094d\u0930\u092e \u0915\u094b \u0926\u094b\u0939\u0930\u093e\u0928\u0947 \u0915\u0947 \u092e\u0941\u0915\u093c\u093e\u092c\u0932\u0947 \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932 \u0938\u094d\u092e\u0943\u0924\u093f \u092a\u0930 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u091c\u093c\u094b\u0930 \u0921\u093e\u0932\u0924\u093e \u0939\u0948\u0964",benefit:"\u092f\u0939 \u0926\u0943\u0936\u094d\u092f-\u0938\u094d\u0925\u093e\u0928\u093f\u0915 \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932 \u0938\u094d\u092e\u0943\u0924\u093f \u0915\u094b \u0938\u0927\u093e\u0924\u093e \u0939\u0948: \u091c\u0917\u0939\u094b\u0902 \u0915\u0947 \u090f\u0915 \u0915\u094d\u0930\u092e \u0915\u094b \u092e\u0928 \u092e\u0947\u0902 \u0925\u093e\u092e\u0928\u093e \u0914\u0930 \u0909\u0938\u0947 \u092e\u0939\u091c\u093c \u092d\u0902\u0921\u093e\u0930\u093f\u0924 \u0915\u0930\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u092e\u093e\u0928\u0938\u093f\u0915 \u0930\u0942\u092a \u0938\u0947 \u0924\u094b\u0921\u093c-\u092e\u0930\u094b\u0921\u093c \u0915\u0930\u0928\u093e\u0964 \u0909\u0932\u094d\u091f\u093e \u0915\u0930\u0928\u0947 \u0935\u093e\u0932\u093e \u091a\u0930\u0923 \u0927\u094d\u092f\u093e\u0928 \u0914\u0930 \u0915\u093e\u0930\u094d\u092f\u0915\u093e\u0930\u0940 \u0928\u093f\u092f\u0902\u0924\u094d\u0930\u0923 \u0915\u094b \u092d\u0940 \u0916\u0940\u0902\u091a \u0932\u093e\u0924\u093e \u0939\u0948, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u0906\u092a\u0915\u094b \u092a\u0942\u0930\u0947 \u0930\u093e\u0938\u094d\u0924\u0947 \u0915\u094b \u0938\u0915\u094d\u0930\u093f\u092f \u0930\u0916\u0924\u0947 \u0939\u0941\u090f \u0909\u0938\u0947 \u0909\u0932\u091f\u0940 \u0926\u093f\u0936\u093e \u092e\u0947\u0902 \u092b\u093f\u0930 \u0938\u0947 \u092c\u0928\u093e\u0928\u093e \u092a\u0921\u093c\u0924\u093e \u0939\u0948\u0964",history:"\u092f\u0939 \u0938\u094d\u0925\u093e\u0928\u093f\u0915-span \u0915\u0940 \u0909\u0938 \u092a\u0930\u0902\u092a\u0930\u093e \u0938\u0947 \u0928\u093f\u0915\u0932\u093e \u0939\u0948 \u091c\u094b \u0915\u094d\u0932\u0940\u0928\u093f\u0915\u0932 \u0924\u0902\u0924\u094d\u0930\u093f\u0915\u093e-\u092e\u0928\u094b\u0935\u093f\u091c\u094d\u091e\u093e\u0928 \u092e\u0947\u0902 Corsi block-tapping \u0915\u093e\u0930\u094d\u092f \u0938\u0947 \u0936\u0941\u0930\u0942 \u0939\u0941\u0908 \u0925\u0940, \u091c\u0939\u093e\u0901 \u0918\u0928\u094b\u0902 \u0915\u094b \u0915\u094d\u0930\u092e \u092e\u0947\u0902 \u0926\u092c\u093e\u0928\u093e \u0938\u094d\u0925\u093e\u0928\u093f\u0915 \u0938\u094d\u092e\u0943\u0924\u093f \u0906\u0901\u0915\u0928\u0947 \u0915\u093e \u090f\u0915 \u092e\u093e\u0928\u0915 \u0924\u0930\u0940\u0915\u093c\u093e \u092c\u0928 \u0917\u092f\u093e\u0964 \u0909\u0932\u094d\u091f\u093e \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0909\u0938\u0940 \u0924\u0930\u094d\u0915 \u092a\u0930 \u091a\u0932\u093e \u091c\u093f\u0938 \u092a\u0930 backward digit span \u2014 \u092f\u093e\u0926 \u0915\u094b \u0909\u0932\u094d\u091f\u093e \u0915\u0930 \u0926\u0947\u0928\u0947 \u0938\u0947 \u0938\u094d\u092e\u0943\u0924\u093f \u092a\u0930 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u092c\u094b\u091d \u2014 \u0914\u0930 \u0909\u0932\u094d\u091f\u093e \u0938\u094d\u0925\u093e\u0928\u093f\u0915 span \u0905\u092c Wechsler Memory Scale \u0914\u0930 Cambridge Cognition \u0915\u0940 Spatial Span \u091c\u0948\u0938\u0940 \u092a\u0930\u0940\u0915\u094d\u0937\u0923-\u0936\u0943\u0902\u0916\u0932\u093e\u0913\u0902 \u092e\u0947\u0902 \u0926\u093f\u092f\u093e \u091c\u093e\u0924\u093e \u0939\u0948\u0964",creator:"backward spatial span \u0915\u093e \u0915\u094b\u0908 \u090f\u0915 \u0906\u0935\u093f\u0937\u094d\u0915\u093e\u0930\u0915 \u0928\u0939\u0940\u0902 \u0939\u0948\u0964 \u0906\u0917\u0947 \u0915\u0940 \u0913\u0930 \u0935\u093e\u0932\u093e \u0915\u093e\u0930\u094d\u092f \u2014 the Corsi block-tapping test \u2014 Philip Corsi \u0928\u0947 \u0905\u092a\u0928\u0947 1972 \u0915\u0947 \u0921\u0949\u0915\u094d\u091f\u0930\u0947\u091f \u0915\u093e\u092e \u092e\u0947\u0902 McGill \u092e\u0947\u0902 Brenda Milner \u0915\u0947 \u0905\u0927\u0940\u0928 \u0935\u093f\u0915\u0938\u093f\u0924 \u0915\u093f\u092f\u093e, \u091c\u094b \u0909\u0928\u0915\u0940 1971 \u0915\u0947 \u0906\u0938\u092a\u093e\u0938 \u0915\u0940 \u092a\u0939\u0932\u0947 \u0915\u0940 \u0930\u093f\u092a\u094b\u0930\u094d\u091f\u094b\u0902 \u092a\u0930 \u091f\u093f\u0915\u093e \u0925\u093e; \u0909\u0932\u094d\u091f\u093e \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0935\u094d\u092f\u093e\u092a\u0915 \u0936\u094b\u0927-\u0938\u092e\u0941\u0926\u093e\u092f \u0926\u094d\u0935\u093e\u0930\u093e \u0915\u093f\u092f\u093e \u0917\u092f\u093e \u090f\u0915 \u092c\u093e\u0926 \u0915\u093e \u0905\u0928\u0941\u0915\u0942\u0932\u0928 \u0939\u0948, \u0914\u0930 \u090f\u0915 \u0909\u0932\u094d\u091f\u093e Spatial Span \u0909\u092a-\u092a\u0930\u0940\u0915\u094d\u0937\u0923 1997 \u092e\u0947\u0902 Wechsler Memory Scale (WMS-III) \u092e\u0947\u0902 \u091c\u094b\u0921\u093c\u093e \u0917\u092f\u093e\u0964",methods:"\u0915\u094b\u0930\u0947 \u092c\u093f\u0902\u0926\u0941\u0913\u0902 \u0915\u094b \u0930\u091f\u0928\u0947 \u0915\u0940 \u0915\u094b\u0936\u093f\u0936 \u092e\u0924 \u0915\u0940\u091c\u093f\u090f \u2014 \u0915\u094d\u0930\u092e \u0915\u094b \u0910\u0938\u0940 \u0906\u0915\u0943\u0924\u093f \u092f\u093e \u0930\u093e\u0938\u094d\u0924\u0947 \u092e\u0947\u0902 \u092c\u0926\u0932 \u0926\u0940\u091c\u093f\u090f \u091c\u093f\u0938\u0947 \u0906\u092a\u0915\u0940 \u0906\u0901\u0916 \u0916\u0940\u0902\u091a \u0938\u0915\u0947, \u092b\u093f\u0930 \u092e\u093e\u0928\u0938\u093f\u0915 \u0930\u0942\u092a \u0938\u0947 \u0909\u0938 \u0930\u093e\u0938\u094d\u0924\u0947 \u092a\u0930 \u0909\u0932\u094d\u091f\u093e \u091a\u0932\u093f\u090f\u0964 \u091c\u0948\u0938\u0947-\u091c\u0948\u0938\u0947 \u0930\u093e\u0938\u094d\u0924\u093e \u0906\u090f, \u0909\u0938\u0915\u0947 \u0938\u093e\u0925-\u0938\u093e\u0925 \u092e\u0928-\u0939\u0940-\u092e\u0928 \u092c\u094b\u0932\u0928\u093e \u092f\u093e \u0909\u0901\u0917\u0932\u0940 \u091a\u0932\u093e\u0928\u093e \u092e\u0926\u0926 \u0915\u0930\u0924\u093e \u0939\u0948; \u0932\u0902\u092c\u0947 \u0915\u094d\u0930\u092e\u094b\u0902 \u0915\u094b \u0926\u094b \u092f\u093e \u0924\u0940\u0928 \u091b\u094b\u091f\u0947 \u091f\u0941\u0915\u0921\u093c\u094b\u0902 \u092e\u0947\u0902 \u092c\u093e\u0901\u091f\u093f\u090f \u0914\u0930 \u0939\u0930 \u090f\u0915 \u0915\u094b \u0909\u0932\u094d\u091f\u093e \u0915\u0940\u091c\u093f\u090f\u0964 \u0932\u0902\u092c\u093e\u0908 \u0924\u092d\u0940 \u092c\u0922\u093c\u093e\u0907\u090f \u091c\u092c \u0906\u092a \u0915\u093f\u0938\u0940 \u0938\u094d\u0924\u0930 \u0915\u094b \u0906\u0930\u093e\u092e \u0938\u0947 \u0938\u093e\u092b\u093c \u0915\u0930 \u0930\u0939\u0947 \u0939\u094b\u0902, \u0914\u0930 \u0926\u094c\u0921\u093c\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u0927\u0940\u092e\u0947 \u0939\u094b\u0915\u0930 \u0932\u093e\u092a\u0930\u0935\u093e\u0939 \u0926\u092c\u093e\u0935\u094b\u0902 \u092e\u0947\u0902 \u0915\u091f\u094c\u0924\u0940 \u0915\u0940\u091c\u093f\u090f\u0964",duration:"\u092e\u0948\u0930\u093e\u0925\u0928 \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u0939\u0948\u0902 \u091b\u094b\u091f\u0947, \u092c\u093e\u0930-\u092c\u093e\u0930 \u0915\u0947 \u0938\u0924\u094d\u0930: \u0930\u094b\u091c\u093c \u092a\u093e\u0901\u091a \u0938\u0947 \u0926\u0938 \u092e\u093f\u0928\u091f, \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u0915\u0941\u091b \u0926\u093f\u0928, \u0915\u093e\u092b\u093c\u0940 \u0939\u0948\u0964 \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932-\u0938\u094d\u092e\u0943\u0924\u093f \u0935\u093e\u0932\u0947 \u0915\u093e\u092e \u091c\u0932\u094d\u0926\u0940 \u0925\u0915\u093e \u0926\u0947\u0924\u0947 \u0939\u0948\u0902, \u0907\u0938\u0932\u093f\u090f \u0930\u0917\u0921\u093c\u0924\u0947 \u0930\u0939\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u091c\u092c \u0938\u091f\u0940\u0915\u0924\u093e \u0917\u093f\u0930\u0928\u0947 \u0932\u0917\u0947 \u0924\u092d\u0940 \u0930\u0941\u0915 \u091c\u093e\u0907\u090f\u0964",research:"\u091c\u094b \u0920\u094b\u0938 \u0939\u0948 \u0935\u0939 \u0938\u0940\u092e\u093f\u0924 \u0914\u0930 \u0905\u0928\u091a\u094c\u0902\u0915\u093e\u0928\u0947 \u0935\u093e\u0932\u093e \u0939\u0948 \u2014 \u0907\u0938\u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0940\u091c\u093f\u090f \u0914\u0930 \u0906\u092a \u0907\u0938\u0940 \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902, \u0909\u0932\u094d\u091f\u0947 \u0938\u094d\u0925\u093e\u0928\u093f\u0915 \u0915\u093e\u0930\u094d\u092f\u094b\u0902 \u0914\u0930 \u0909\u0928\u0938\u0947 \u092e\u093f\u0932\u0924\u0947-\u091c\u0941\u0932\u0924\u0947 \u0915\u093e\u0930\u094d\u092f\u094b\u0902 \u092e\u0947\u0902 \u0905\u092a\u0928\u093e span \u0938\u0941\u0927\u093e\u0930\u0924\u0947 \u0939\u0941\u090f\u0964 \u092c\u0921\u093c\u0947 \u0926\u093e\u0935\u0947 \u0935\u0939\u0940\u0902 \u092c\u093f\u0916\u0930 \u091c\u093e\u0924\u0947 \u0939\u0948\u0902: \u092c\u0921\u093c\u0947 \u092e\u0947\u091f\u093e-\u0935\u093f\u0936\u094d\u0932\u0947\u0937\u0923 (Melby-Lerv\xe5g \u0914\u0930 \u0938\u0939\u092f\u094b\u0917\u0940, 2016) \u092a\u093e\u0924\u0947 \u0939\u0948\u0902 \u0915\u093f \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932-\u0938\u094d\u092e\u0943\u0924\u093f \u0915\u0940 \u091f\u094d\u0930\u0947\u0928\u093f\u0902\u0917 \u0915\u093e\u0930\u094d\u092f-\u0935\u093f\u0936\u093f\u0937\u094d\u091f \u0932\u093e\u092d \u0926\u0947\u0924\u0940 \u0939\u0948 \u091c\u094b \u092c\u0941\u0926\u094d\u0927\u093f \u092f\u093e \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0940 \u0938\u094b\u091a \u0924\u0915 \u0928\u0939\u0940\u0902 \u092b\u0948\u0932\u0924\u0947, \u0907\u0938\u0932\u093f\u090f \u092f\u0947 \u0935\u093e\u0926\u0947 \u0915\u093f \u092f\u0939 IQ \u092c\u0922\u093c\u093e\u0924\u093e \u0939\u0948, \u0906\u092e '\u0926\u093f\u092e\u093e\u0917\u0940 \u0924\u093e\u0915\u093c\u0924' \u092c\u0922\u093c\u093e\u0924\u093e \u0939\u0948, \u092f\u093e \u0938\u0902\u091c\u094d\u091e\u093e\u0928\u093e\u0924\u094d\u092e\u0915 \u0917\u093f\u0930\u093e\u0935\u091f \u0915\u094b \u0930\u094b\u0915\u0924\u093e \u0939\u0948, \u0938\u092c\u0942\u0924\u094b\u0902 \u0938\u0947 \u0938\u092e\u0930\u094d\u0925\u093f\u0924 \u0928\u0939\u0940\u0902 \u0939\u0948\u0902\u0964 \u0907\u0938\u0947 \u090f\u0915 \u0916\u093c\u093e\u0938 \u0915\u094c\u0936\u0932 \u0915\u0940 \u090f\u0915\u093e\u0917\u094d\u0930 \u0915\u0938\u0930\u0924 \u092e\u093e\u0928\u093f\u090f, \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0939\u094b\u0936\u093f\u092f\u093e\u0930 \u092c\u0928\u0928\u0947 \u0915\u0940 \u0936\u0949\u0930\u094d\u091f\u0915\u091f \u0928\u0939\u0940\u0902\u0964",rec:"\u0910\u0938\u0940 \u0932\u0902\u092c\u093e\u0908 \u092a\u0930 \u0938\u093e\u092b\u093c-\u0938\u0941\u0925\u0930\u0947 \u0909\u0932\u091f\u093e\u0935\u094b\u0902 \u0915\u0947 \u092a\u0940\u091b\u0947 \u092d\u093e\u0917\u093f\u090f \u091c\u093f\u0938\u0947 \u0906\u092a \u0938\u091a\u092e\u0941\u091a \u0925\u093e\u092e \u0938\u0915\u0947\u0902, \u0914\u0930 \u0915\u0920\u093f\u0928\u093e\u0908 \u0924\u092d\u0940 \u092c\u0922\u093c\u093e\u0907\u090f \u091c\u092c \u0935\u0939 \u0932\u0902\u092c\u093e\u0908 \u0906\u0938\u093e\u0928 \u092e\u0939\u0938\u0942\u0938 \u0939\u094b\u0928\u0947 \u0932\u0917\u0947\u0964",faq:[["\u0909\u0932\u094d\u091f\u093e \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0906\u0917\u0947 \u0935\u093e\u0932\u0947 \u0938\u0947 \u0915\u0920\u093f\u0928 \u0915\u094d\u092f\u094b\u0902 \u0939\u0948?","\u0915\u093f\u0938\u0940 \u0930\u093e\u0938\u094d\u0924\u0947 \u0915\u094b \u0906\u0917\u0947 \u0915\u0940 \u0913\u0930 \u0926\u094b\u0939\u0930\u093e\u0928\u093e \u091c\u093c\u094d\u092f\u093e\u0926\u093e\u0924\u0930 \u092d\u0902\u0921\u093e\u0930\u0923 \u0915\u094b \u092a\u0930\u0916\u0924\u093e \u0939\u0948, \u092a\u0930 \u0909\u0938\u0947 \u0909\u0932\u094d\u091f\u093e \u0915\u0930\u0928\u093e \u0906\u092a\u0915\u094b \u092a\u0942\u0930\u0947 \u0915\u094d\u0930\u092e \u0915\u094b \u0938\u0915\u094d\u0930\u093f\u092f \u0930\u0916\u0915\u0930 \u0909\u0932\u091f\u0940 \u0926\u093f\u0936\u093e \u092e\u0947\u0902 \u092b\u093f\u0930 \u0938\u0947 \u092c\u0928\u093e\u0928\u0947 \u092a\u0930 \u092e\u091c\u092c\u0942\u0930 \u0915\u0930\u0924\u093e \u0939\u0948, \u091c\u094b \u0938\u094d\u092e\u0943\u0924\u093f \u0915\u0947 \u090a\u092a\u0930 \u090f\u0915 \u0905\u0924\u093f\u0930\u093f\u0915\u094d\u0924 \u0924\u094b\u0921\u093c-\u092e\u0930\u094b\u0921\u093c \u0915\u093e \u091a\u0930\u0923 \u091c\u094b\u0921\u093c \u0926\u0947\u0924\u093e \u0939\u0948\u0964"],["\u0915\u094d\u092f\u093e \u0907\u0938\u0938\u0947 \u092e\u0948\u0902 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0939\u094b\u0936\u093f\u092f\u093e\u0930 \u092c\u0928 \u091c\u093e\u090a\u0901\u0917\u093e \u092f\u093e \u092e\u0947\u0930\u093e IQ \u092c\u0922\u093c\u0947\u0917\u093e?","\u0928\u0939\u0940\u0902\u0964 \u0938\u092c\u0942\u0924 \u0926\u093f\u0916\u093e\u0924\u0947 \u0939\u0948\u0902 \u0915\u093f \u0906\u092a \u0916\u093c\u0941\u0926 \u0907\u0938 \u0915\u093e\u092e \u092e\u0947\u0902 \u0914\u0930 \u0907\u0938\u0915\u0947 \u0928\u091c\u093c\u0926\u0940\u0915\u0940 \u0930\u093f\u0936\u094d\u0924\u0947\u0926\u093e\u0930\u094b\u0902 \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902, \u092a\u0930 \u0935\u0947 \u0932\u093e\u092d \u092c\u0941\u0926\u094d\u0927\u093f \u092f\u093e \u0905\u0938\u0932\u0940-\u0926\u0941\u0928\u093f\u092f\u093e \u0915\u0940 \u0938\u094b\u091a \u0924\u0915 \u0928\u0939\u0940\u0902 \u092a\u0939\u0941\u0901\u091a\u0924\u0947, \u0907\u0938\u0932\u093f\u090f \u0907\u0938\u0947 \u090f\u0915 \u0926\u093f\u092e\u093e\u0917\u0940 \u0905\u092a\u0917\u094d\u0930\u0947\u0921 \u0915\u0947 \u092c\u091c\u093e\u092f \u090f\u0915 \u0932\u0915\u094d\u0937\u093f\u0924 \u0905\u092d\u094d\u092f\u093e\u0938 \u092e\u093e\u0928\u0928\u093e \u0939\u0940 \u0938\u092c\u0938\u0947 \u0905\u091a\u094d\u091b\u093e \u0939\u0948\u0964"],["\u092f\u0939 backward digit span \u0938\u0947 \u0915\u0948\u0938\u0947 \u0905\u0932\u0917 \u0939\u0948?","\u0935\u093f\u091a\u093e\u0930 \u0935\u0939\u0940 \u0939\u0948, \u0938\u093e\u092e\u0917\u094d\u0930\u0940 \u0905\u0932\u0917: digit span \u0938\u0902\u0916\u094d\u092f\u093e\u0913\u0902 \u0915\u0940 \u090f\u0915 \u0936\u0943\u0902\u0916\u0932\u093e \u0915\u094b \u0909\u0932\u094d\u091f\u093e \u0915\u0930\u0924\u093e \u0939\u0948 \u0914\u0930 \u092e\u094c\u0916\u093f\u0915 \u0938\u094d\u092e\u0943\u0924\u093f \u092a\u0930 \u091f\u093f\u0915\u093e \u0939\u0948, \u091c\u092c\u0915\u093f spatial span \u091c\u0917\u0939\u094b\u0902 \u0915\u0947 \u090f\u0915 \u0915\u094d\u0930\u092e \u0915\u094b \u0909\u0932\u094d\u091f\u093e \u0915\u0930\u0924\u093e \u0939\u0948 \u0914\u0930 \u0926\u0943\u0936\u094d\u092f-\u0938\u094d\u0925\u093e\u0928\u093f\u0915 \u0938\u094d\u092e\u0943\u0924\u093f \u092a\u0930 \u091f\u093f\u0915\u093e \u0939\u0948\u0964"]],variants:"\u0906\u0917\u0947 \u0915\u0940 \u0913\u0930 \u0935\u093e\u0932\u093e \u0938\u094d\u0925\u093e\u0928\u093f\u0915 span (\u0909\u0938\u0940 \u0915\u094d\u0930\u092e \u092e\u0947\u0902 \u0926\u094b\u0939\u0930\u093e\u0928\u093e) \u0906\u0938\u093e\u0928 \u0906\u0927\u093e\u0930-\u0930\u0947\u0916\u093e \u0939\u0948; \u0915\u094d\u0932\u093e\u0938\u093f\u0915 \u092d\u094c\u0924\u093f\u0915 \u0930\u0942\u092a \u0928\u094c \u0918\u0928\u094b\u0902 \u0935\u093e\u0932\u093e Corsi block-tapping test \u0939\u0948\u0964 \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0917\u094d\u0930\u093f\u0921 \u0915\u093e \u0906\u0915\u093e\u0930, \u0915\u094d\u0930\u092e \u0915\u0940 \u0930\u092b\u093c\u094d\u0924\u093e\u0930, \u0914\u0930 \u0930\u093e\u0938\u094d\u0924\u0947 \u0915\u0940 \u0932\u0902\u092c\u093e\u0908 \u092c\u0926\u0932\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 backward digit span \u091c\u0948\u0938\u0947 \u092e\u094c\u0916\u093f\u0915 \u0930\u093f\u0936\u094d\u0924\u0947\u0926\u093e\u0930 \u0935\u0939\u0940 \u0909\u0932\u094d\u091f\u0940-\u092f\u093e\u0926 \u0935\u093e\u0932\u093e \u0935\u093f\u091a\u093e\u0930 \u091c\u0917\u0939\u094b\u0902 \u0915\u0947 \u092c\u091c\u093e\u092f \u0938\u0902\u0916\u094d\u092f\u093e\u0913\u0902 \u092a\u0930 \u0932\u0917\u093e\u0924\u0947 \u0939\u0948\u0902\u0964"},zh:{about:"\u65b9\u683c\u91cc\u7684\u4e00\u4e2a\u4e2a\u9762\u677f\u4f9d\u6b21\u4eae\u8d77\uff0c\u4f60\u8981\u6309\u76f8\u53cd\u7684\u987a\u5e8f\u70b9\u56de\u53bb\u6765\u590d\u73b0\u8fd9\u6bb5\u5e8f\u5217\u2014\u2014\u6700\u540e\u4eae\u7684\u5148\u70b9\uff0c\u4e00\u8def\u70b9\u56de\u8d77\u70b9\u3002\u56e0\u4e3a\u4f60\u5f97\u628a\u6574\u6761\u8def\u5f84\u8bb0\u5728\u8111\u4e2d\u518d\u5012\u7740\u8dd1\u4e00\u904d\uff0c\u5b83\u5bf9\u5de5\u4f5c\u8bb0\u5fc6\u7684\u4f9d\u8d56\u6bd4\u5355\u7eaf\u7167\u642c\u4f60\u770b\u5230\u7684\u987a\u5e8f\u8981\u91cd\u5f97\u591a\u3002",benefit:"\u5b83\u8bad\u7ec3\u89c6\u7a7a\u95f4\u5de5\u4f5c\u8bb0\u5fc6\uff1a\u628a\u4e00\u7ec4\u4f4d\u7f6e\u5e8f\u5217\u8bb0\u5728\u8111\u4e2d\u5e76\u5bf9\u5176\u8fdb\u884c\u5fc3\u7406\u64cd\u4f5c\uff0c\u800c\u4e0d\u53ea\u662f\u5b58\u50a8\u3002\u5012\u5e8f\u8fd9\u4e00\u6b65\u8fd8\u4f1a\u8c03\u52a8\u6ce8\u610f\u529b\u548c\u6267\u884c\u63a7\u5236\uff0c\u56e0\u4e3a\u4f60\u5f97\u8ba9\u6574\u6761\u8def\u5f84\u4fdd\u6301\u6fc0\u6d3b\uff0c\u540c\u65f6\u6309\u76f8\u53cd\u65b9\u5411\u628a\u5b83\u91cd\u5efa\u51fa\u6765\u3002",history:"\u5b83\u6e90\u81ea\u7a7a\u95f4\u5e7f\u5ea6\u4f20\u7edf\uff0c\u800c\u8fd9\u4e00\u4f20\u7edf\u59cb\u4e8e\u4e34\u5e8a\u795e\u7ecf\u5fc3\u7406\u5b66\u4e2d\u7684Corsi\u65b9\u5757\u6572\u51fb\u4efb\u52a1\u2014\u2014\u6309\u987a\u5e8f\u6572\u51fb\u65b9\u5757\u6210\u4e86\u8861\u91cf\u7a7a\u95f4\u8bb0\u5fc6\u7684\u6807\u51c6\u65b9\u6cd5\u3002\u5012\u5e8f\u7248\u672c\u9075\u5faa\u7684\u903b\u8f91\u4e0e\u5012\u5e8f\u6570\u5b57\u5e7f\u5ea6\u76f8\u540c\u2014\u2014\u628a\u56de\u5fc6\u53cd\u8fc7\u6765\u4ee5\u66f4\u91cd\u5730\u52a0\u8d1f\u8377\u4e8e\u8bb0\u5fc6\u2014\u2014\u5982\u4eca\u5012\u5e8f\u7a7a\u95f4\u5e7f\u5ea6\u5df2\u88ab\u7eb3\u5165\u97e6\u6c0f\u8bb0\u5fc6\u91cf\u8868\uff08Wechsler Memory Scale\uff09\u4ee5\u53caCambridge Cognition\u7684Spatial Span\u7b49\u6d4b\u9a8c\u7ec4\u5408\u4e2d\u3002",creator:"\u5012\u5e8f\u7a7a\u95f4\u5e7f\u5ea6\u6ca1\u6709\u5355\u4e00\u7684\u53d1\u660e\u8005\u3002\u6b63\u5e8f\u4efb\u52a1\u2014\u2014\u5373Corsi\u65b9\u5757\u6572\u51fb\u6d4b\u9a8c\u2014\u2014\u7531Philip Corsi\u57281972\u5e74\u7684\u535a\u58eb\u5de5\u4f5c\u4e2d\u5f00\u53d1\uff0c\u5bfc\u5e08\u662f\u9ea6\u5409\u5c14\u5927\u5b66\u7684Brenda Milner\uff0c\u5e76\u5efa\u7acb\u5728\u5979\u7ea61971\u5e74\u7684\u65e9\u671f\u62a5\u544a\u4e4b\u4e0a\uff1b\u5012\u5e8f\u53d8\u4f53\u662f\u540e\u6765\u7531\u66f4\u5e7f\u6cdb\u7684\u7814\u7a76\u754c\u6539\u7f16\u800c\u6765\u7684\uff0c\u800c\u5012\u5e8f\u7684Spatial Span\u5206\u6d4b\u9a8c\u4e8e1997\u5e74\u88ab\u52a0\u5165\u97e6\u6c0f\u8bb0\u5fc6\u91cf\u8868\uff08WMS-III\uff09\u3002",methods:"\u522b\u53bb\u786c\u8bb0\u4e00\u4e2a\u4e2a\u5b64\u7acb\u7684\u70b9\u2014\u2014\u628a\u5e8f\u5217\u53d8\u6210\u4e00\u4e2a\u5f62\u72b6\u6216\u4e00\u6761\u4f60\u773c\u775b\u80fd\u63cf\u51fa\u6765\u7684\u8def\u5f84\uff0c\u7136\u540e\u5728\u8111\u4e2d\u5012\u7740\u8d70\u4e00\u904d\u8fd9\u6761\u8def\u5f84\u3002\u5728\u9762\u677f\u4eae\u8d77\u65f6\u9ed8\u5ff5\u6216\u7528\u624b\u6307\u6cbf\u8def\u6307\u4e00\u6307\u4f1a\u6709\u5e2e\u52a9\uff1b\u628a\u8f83\u957f\u7684\u5e8f\u5217\u5207\u6210\u4e24\u4e09\u5c0f\u6bb5\uff0c\u518d\u9010\u6bb5\u5012\u5e8f\u3002\u53ea\u6709\u5f53\u4f60\u80fd\u8f7b\u677e\u901a\u5173\u65f6\u624d\u628a\u957f\u5ea6\u5f80\u4e0a\u52a0\uff0c\u5e76\u653e\u6162\u901f\u5ea6\u4ee5\u51cf\u5c11\u9a6c\u864e\u7684\u8bef\u70b9\uff0c\u800c\u4e0d\u662f\u56fe\u5feb\u3002",duration:"\u77ed\u800c\u9891\u7e41\u7684\u7ec3\u4e60\u80dc\u8fc7\u9a6c\u62c9\u677e\uff1a\u6bcf\u5929\u4e94\u5230\u5341\u5206\u949f\u3001\u4e00\u5468\u51e0\u5929\uff0c\u5c31\u8db3\u591f\u4e86\u3002\u5de5\u4f5c\u8bb0\u5fc6\u4efb\u52a1\u5f88\u5feb\u5c31\u8ba9\u4eba\u75b2\u52b3\uff0c\u6240\u4ee5\u51c6\u786e\u7387\u5f00\u59cb\u4e0b\u6ed1\u65f6\u5c31\u505c\uff0c\u522b\u786c\u78e8\u3002",research:"\u624e\u5b9e\u7684\u7ed3\u8bba\u65e2\u72ed\u7a84\u53c8\u6beb\u4e0d\u610f\u5916\u2014\u2014\u7ec3\u8fd9\u4e2a\uff0c\u4f60\u5c31\u4f1a\u5728\u8fd9\u4e2a\u4e0a\u53d8\u597d\uff0c\u5728\u5012\u5e8f\u7a7a\u95f4\u4efb\u52a1\u53ca\u7c7b\u4f3c\u4efb\u52a1\u4e0a\u7684\u5e7f\u5ea6\u4f1a\u63d0\u5347\u3002\u95ee\u9898\u51fa\u5728\u90a3\u4e9b\u66f4\u5927\u7684\u8bf4\u6cd5\u4e0a\uff1a\u5927\u578b\u5143\u5206\u6790\uff08Melby-Lerv\xe5g\u7b49\u4eba\uff0c2016\uff09\u53d1\u73b0\uff0c\u5de5\u4f5c\u8bb0\u5fc6\u8bad\u7ec3\u5e26\u6765\u7684\u662f\u4efb\u52a1\u7279\u5b9a\u7684\u6536\u76ca\uff0c\u5e76\u4e0d\u4f1a\u6cdb\u5316\u5230\u667a\u529b\u6216\u65e5\u5e38\u8ba4\u77e5\uff0c\u6240\u4ee5\u300c\u5b83\u80fd\u63d0\u9ad8\u667a\u5546\u3001\u589e\u5f3a\u6574\u4f53\u8111\u529b\u6216\u62b5\u5fa1\u8ba4\u77e5\u8870\u9000\u300d\u4e4b\u7c7b\u7684\u627f\u8bfa\u5e76\u65e0\u4f9d\u636e\u3002\u628a\u5b83\u5f53\u6210\u9488\u5bf9\u67d0\u9879\u7279\u5b9a\u6280\u80fd\u7684\u4e13\u6ce8\u953b\u70bc\uff0c\u800c\u975e\u53d8\u806a\u660e\u7684\u6377\u5f84\u3002",rec:"\u5728\u4f60\u771f\u6b63\u80fd\u8bb0\u4f4f\u7684\u957f\u5ea6\u4e0a\uff0c\u53bb\u8ffd\u6c42\u5e72\u51c0\u5229\u843d\u7684\u5012\u5e8f\u590d\u73b0\uff1b\u53ea\u6709\u5f53\u90a3\u4e2a\u957f\u5ea6\u73a9\u8d77\u6765\u8f7b\u677e\u4e86\uff0c\u518d\u628a\u96be\u5ea6\u5f80\u4e0a\u52a0\u3002",faq:[["\u4e3a\u4ec0\u4e48\u5012\u5e8f\u7248\u672c\u6bd4\u6b63\u5e8f\u66f4\u96be\uff1f","\u6b63\u7740\u590d\u73b0\u4e00\u6761\u8def\u5f84\u4e3b\u8981\u8003\u9a8c\u5b58\u50a8\uff0c\u800c\u628a\u5b83\u53cd\u8fc7\u6765\u5219\u903c\u4f60\u8ba9\u6574\u6761\u5e8f\u5217\u4fdd\u6301\u6fc0\u6d3b\uff0c\u5e76\u6309\u76f8\u53cd\u65b9\u5411\u91cd\u5efa\u5b83\u2014\u2014\u8fd9\u5728\u8bb0\u5fc6\u4e4b\u4e0a\u53c8\u52a0\u4e86\u4e00\u9053\u989d\u5916\u7684\u64cd\u4f5c\u6b65\u9aa4\u3002"],["\u7ec3\u8fd9\u4e2a\u4f1a\u8ba9\u6211\u53d8\u806a\u660e\u6216\u63d0\u9ad8\u667a\u5546\u5417\uff1f","\u4e0d\u4f1a\u3002\u8bc1\u636e\u8868\u660e\u4f60\u4f1a\u5728\u4efb\u52a1\u672c\u8eab\u548c\u8fd1\u4eb2\u4efb\u52a1\u4e0a\u53d8\u597d\uff0c\u4f46\u8fd9\u4e9b\u6536\u76ca\u4e0d\u4f1a\u8fc1\u79fb\u5230\u667a\u529b\u6216\u73b0\u5b9e\u4e16\u754c\u7684\u601d\u8003\u4e0a\uff0c\u6240\u4ee5\u6700\u597d\u628a\u5b83\u770b\u4f5c\u6709\u9488\u5bf9\u6027\u7684\u7ec3\u4e60\uff0c\u800c\u975e\u7ed9\u5927\u8111\u5347\u7ea7\u3002"],["\u8fd9\u548c\u5012\u5e8f\u6570\u5b57\u5e7f\u5ea6\u6709\u4ec0\u4e48\u533a\u522b\uff1f","\u601d\u8def\u76f8\u540c\uff0c\u6750\u6599\u4e0d\u540c\uff1a\u6570\u5b57\u5e7f\u5ea6\u662f\u628a\u4e00\u4e32\u6570\u5b57\u5012\u8fc7\u6765\uff0c\u4f9d\u8d56\u8a00\u8bed\u8bb0\u5fc6\uff1b\u800c\u7a7a\u95f4\u5e7f\u5ea6\u662f\u628a\u4e00\u7ec4\u4f4d\u7f6e\u5e8f\u5217\u5012\u8fc7\u6765\uff0c\u4f9d\u8d56\u89c6\u7a7a\u95f4\u8bb0\u5fc6\u3002"]],variants:"\u6b63\u5e8f\u7a7a\u95f4\u5e7f\u5ea6\uff08\u6309\u76f8\u540c\u987a\u5e8f\u590d\u73b0\uff09\u662f\u8f83\u5bb9\u6613\u7684\u57fa\u7ebf\uff1b\u7ecf\u5178\u7684\u5b9e\u4f53\u5f62\u5f0f\u662f\u5e26\u4e5d\u4e2a\u65b9\u5757\u7684Corsi\u65b9\u5757\u6572\u51fb\u6d4b\u9a8c\u3002\u5404\u53d8\u4f53\u4f1a\u8c03\u6574\u65b9\u683c\u5c3a\u5bf8\u3001\u5e8f\u5217\u901f\u5ea6\u548c\u8def\u5f84\u957f\u5ea6\uff0c\u800c\u50cf\u5012\u5e8f\u6570\u5b57\u5e7f\u5ea6\u8fd9\u6837\u7684\u8a00\u8bed\u8fd1\u4eb2\uff0c\u5219\u628a\u540c\u6837\u7684\u300c\u53cd\u5411\u56de\u5fc6\u300d\u601d\u8def\u7528\u5728\u6570\u5b57\u800c\u975e\u4f4d\u7f6e\u4e0a\u3002"}},"stop-signal":{ru:{about:"\xabStop-Signal: \u0422\u043e\u0440\u043c\u043e\u0436\u0435\u043d\u0438\u0435\xbb \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u0443\u043c\u0435\u043d\u0438\u0435 \u043e\u0431\u043e\u0440\u0432\u0430\u0442\u044c \u0443\u0436\u0435 \u043d\u0430\u0447\u0430\u0442\u043e\u0435 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435. \u0412\u044b \u043a\u0430\u043a \u043c\u043e\u0436\u043d\u043e \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u0440\u0435\u0430\u0433\u0438\u0440\u0443\u0435\u0442\u0435 \u043d\u0430 \u043f\u043e\u0442\u043e\u043a \u0441\u0438\u0433\u043d\u0430\u043b\u043e\u0432 (\u043d\u0430\u043f\u0440\u0438\u043c\u0435\u0440, \u043d\u0430\u0436\u0438\u043c\u0430\u0435\u0442\u0435 \u0432\u043b\u0435\u0432\u043e \u0438\u043b\u0438 \u0432\u043f\u0440\u0430\u0432\u043e \u0432 \u0437\u0430\u0432\u0438\u0441\u0438\u043c\u043e\u0441\u0442\u0438 \u043e\u0442 \u0441\u0442\u0440\u0435\u043b\u043a\u0438), \u043d\u043e \u0432 \u0447\u0430\u0441\u0442\u0438 \u043f\u043e\u043f\u044b\u0442\u043e\u043a \u0441\u043f\u0443\u0441\u0442\u044f \u0434\u043e\u043b\u044e \u0441\u0435\u043a\u0443\u043d\u0434\u044b \u043f\u043e\u044f\u0432\u043b\u044f\u0435\u0442\u0441\u044f \u0441\u0442\u043e\u043f-\u0441\u0438\u0433\u043d\u0430\u043b, \u0438 \u0442\u043e\u0433\u0434\u0430 \u043d\u0443\u0436\u043d\u043e \u0443\u0441\u043f\u0435\u0442\u044c \u043e\u0442\u043c\u0435\u043d\u0438\u0442\u044c \u0434\u0432\u0438\u0436\u0435\u043d\u0438\u0435, \u043a\u043e\u0442\u043e\u0440\u043e\u0435 \u0432\u044b \u0443\u0436\u0435 \u0437\u0430\u043f\u0443\u0441\u043a\u0430\u043b\u0438.",benefit:"\u0423\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u0435 \u043f\u0440\u043e\u043a\u0430\u0447\u0438\u0432\u0430\u0435\u0442 \u0442\u043e\u0440\u043c\u043e\u0436\u0435\u043d\u0438\u0435 \u0440\u0435\u0430\u043a\u0446\u0438\u0438 \u2014 \u0441\u043f\u043e\u0441\u043e\u0431\u043d\u043e\u0441\u0442\u044c \u0443\u043f\u0440\u0430\u0432\u043b\u044f\u044e\u0449\u0435\u0433\u043e \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044f \u043e\u0442\u043c\u0435\u043d\u0438\u0442\u044c \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435 \u043d\u0430 \u043f\u043e\u043b\u043f\u0443\u0442\u0438. \u042d\u0442\u043e \u0442\u043e\u0442 \u0436\u0435 \u043c\u0435\u0445\u0430\u043d\u0438\u0437\u043c, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0435\u0442 \u0432\u0430\u0441 \u043e\u0442 \u0440\u0435\u0444\u043b\u0435\u043a\u0442\u043e\u0440\u043d\u043e\u0433\u043e \u0436\u0435\u0441\u0442\u0430, \u043f\u043e\u043c\u043e\u0433\u0430\u0435\u0442 \u0441\u043f\u043e\u0445\u0432\u0430\u0442\u0438\u0442\u044c\u0441\u044f \u043f\u0435\u0440\u0435\u0434 \u043e\u0448\u0438\u0431\u043a\u043e\u0439 \u0438\u043b\u0438 \u043d\u0435 \u043f\u043e\u0442\u044f\u043d\u0443\u0442\u044c\u0441\u044f \u0437\u0430 \u0447\u0435\u043c-\u0442\u043e \u043d\u0430 \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0435.",history:"\u0418\u0434\u0435\u044f \u0433\u0430\u0441\u0438\u0442\u044c \u0443\u0436\u0435 \u0437\u0430\u043f\u0443\u0449\u0435\u043d\u043d\u0443\u044e \u0440\u0435\u0430\u043a\u0446\u0438\u044e \u0441 \u043f\u043e\u043c\u043e\u0449\u044c\u044e \u0437\u0430\u043f\u0430\u0437\u0434\u044b\u0432\u0430\u044e\u0449\u0435\u0433\u043e \u0441\u0438\u0433\u043d\u0430\u043b\u0430 \u0432\u043e\u0441\u0445\u043e\u0434\u0438\u0442 \u043a \u0440\u0430\u0431\u043e\u0442\u0435 \u041b\u0430\u043f\u043f\u0438\u043d\u0430 \u0438 \u042d\u0440\u0438\u043a\u0441\u0435\u043d\u0430 1966 \u0433\u043e\u0434\u0430. \u0422\u043e\u0447\u043d\u044b\u043c \u0438\u0437\u043c\u0435\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u043c \u0438\u043d\u0441\u0442\u0440\u0443\u043c\u0435\u043d\u0442\u043e\u043c \u043e\u043d\u0430 \u0441\u0442\u0430\u043b\u0430 \u0432 1984-\u043c, \u043a\u043e\u0433\u0434\u0430 \u041b\u043e\u0433\u0430\u043d \u0438 \u041a\u043e\u0443\u044d\u043d \u043e\u043f\u0438\u0441\u0430\u043b\u0438 \u043c\u043e\u0434\u0435\u043b\u044c \xab\u0433\u043e\u043d\u043a\u0438\xbb \u0434\u0432\u0443\u0445 \u043f\u0440\u043e\u0446\u0435\u0441\u0441\u043e\u0432, \u0430 \u0441 1990-\u0445 \u0440\u0430\u0441\u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0438\u043b\u0430\u0441\u044c \u0432 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u044f\u0445 \u0421\u0414\u0412\u0413, \u0437\u0430\u0432\u0438\u0441\u0438\u043c\u043e\u0441\u0442\u0435\u0439 \u0438 \u0438\u043c\u043f\u0443\u043b\u044c\u0441\u0438\u0432\u043d\u043e\u0441\u0442\u0438, \u043f\u043e\u0437\u0436\u0435 \u043f\u043e\u043f\u0430\u0432 \u0438 \u0432 \u043f\u0440\u0438\u043b\u043e\u0436\u0435\u043d\u0438\u044f \u0434\u043b\u044f \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0438 \u043c\u043e\u0437\u0433\u0430.",creator:"\u0423 \u0441\u0430\u043c\u043e\u0439 \u0438\u0434\u0435\u0438 \u043d\u0435\u0442 \u0435\u0434\u0438\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0433\u043e \u0430\u0432\u0442\u043e\u0440\u0430. \u0420\u0430\u043d\u043d\u0438\u0439 \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0439 \u0432\u0430\u0440\u0438\u0430\u043d\u0442 \u0441\u043e \u0441\u0442\u043e\u043f-\u0441\u0438\u0433\u043d\u0430\u043b\u043e\u043c \u043e\u043f\u0443\u0431\u043b\u0438\u043a\u043e\u0432\u0430\u043b\u0438 \u0414\u0436\u043e\u0437\u0435\u0444 \u041b\u0430\u043f\u043f\u0438\u043d \u0438 \u0427\u0430\u0440\u043b\u044c\u0437 \u042d\u0440\u0438\u043a\u0441\u0435\u043d \u0432 1966 \u0433\u043e\u0434\u0443, \u0430 \u0441\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u0443\u044e \u0432\u0435\u0440\u0441\u0438\u044e \u0441 \u0438\u0437\u043c\u0435\u0440\u0438\u043c\u044b\u043c \u0432\u0440\u0435\u043c\u0435\u043d\u0435\u043c \u0442\u043e\u0440\u043c\u043e\u0436\u0435\u043d\u0438\u044f \u0441\u043e\u0437\u0434\u0430\u043b\u0438 \u0413\u043e\u0440\u0434\u043e\u043d \u041b\u043e\u0433\u0430\u043d \u0438 \u0423\u0438\u043b\u044c\u044f\u043c \u041a\u043e\u0443\u044d\u043d \u0432 1984-\u043c \u0432 \u0441\u0442\u0430\u0442\u044c\u0435 \xabOn the ability to inhibit simple and choice reaction time responses\xbb.",methods:"\u0412\u044b\u043a\u043b\u0430\u0434\u044b\u0432\u0430\u0439\u0442\u0435\u0441\u044c \u043d\u0430 \u043a\u0430\u0436\u0434\u043e\u0439 \u043f\u043e\u043f\u044b\u0442\u043a\u0435 \u043f\u043e-\u043d\u0430\u0441\u0442\u043e\u044f\u0449\u0435\u043c\u0443: \u0441\u043f\u0435\u0446\u0438\u0430\u043b\u044c\u043d\u043e \u043f\u0440\u0438\u0442\u043e\u0440\u043c\u0430\u0436\u0438\u0432\u0430\u0442\u044c, \u0447\u0442\u043e\u0431\u044b \u0443\u0441\u043f\u0435\u0442\u044c \u043d\u0430 \u0441\u0442\u043e\u043f-\u0441\u0438\u0433\u043d\u0430\u043b, \u2014 \u044d\u0442\u043e \u0441\u0430\u043c\u043e\u043e\u0431\u043c\u0430\u043d, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u0440\u0443\u0448\u0438\u0442 \u0432\u0435\u0441\u044c \u0437\u0430\u043c\u0435\u0440. \u0414\u0435\u0440\u0436\u0438\u0442\u0435 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u043d\u0430\u0433\u043e\u0442\u043e\u0432\u0435, \u043d\u043e \u043d\u0435\u0439\u0442\u0440\u0430\u043b\u044c\u043d\u043e, \u0440\u0435\u0430\u0433\u0438\u0440\u0443\u0439\u0442\u0435 \u043d\u0430 \u0441\u0442\u043e\u043f-\u0441\u0438\u0433\u043d\u0430\u043b, \u0430 \u043d\u0435 \u0443\u0433\u0430\u0434\u044b\u0432\u0430\u0439\u0442\u0435 \u0435\u0433\u043e, \u0438 \u043f\u0443\u0441\u0442\u044c \u0441\u043b\u043e\u0436\u043d\u043e\u0441\u0442\u044c \u043f\u043e\u0434\u0441\u0442\u0440\u0430\u0438\u0432\u0430\u0435\u0442\u0441\u044f \u0442\u0430\u043a, \u0447\u0442\u043e\u0431\u044b \u0432\u044b \u0443\u0441\u043f\u0435\u0448\u043d\u043e \u0442\u043e\u0440\u043c\u043e\u0437\u0438\u043b\u0438 \u043f\u0440\u0438\u043c\u0435\u0440\u043d\u043e \u0432 \u043f\u043e\u043b\u043e\u0432\u0438\u043d\u0435 \u0441\u0442\u043e\u043f-\u043f\u043e\u043f\u044b\u0442\u043e\u043a \u2014 \u0438\u043c\u0435\u043d\u043d\u043e \u0442\u0430\u043c \u0438\u0434\u0451\u0442 \u043d\u0430\u0441\u0442\u043e\u044f\u0449\u0430\u044f \u0440\u0430\u0431\u043e\u0442\u0430.",duration:"\u041a\u043e\u0440\u043e\u0442\u043a\u0438\u0435 \u0447\u0430\u0441\u0442\u044b\u0435 \u043f\u043e\u0434\u0445\u043e\u0434\u044b \u043b\u0443\u0447\u0448\u0435 \u043c\u0430\u0440\u0430\u0444\u043e\u043d\u043e\u0432: 10\u201315 \u043c\u0438\u043d\u0443\u0442 \u0442\u0440\u0438-\u0447\u0435\u0442\u044b\u0440\u0435 \u0440\u0430\u0437\u0430 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e \u0432\u043f\u043e\u043b\u043d\u0435 \u0434\u043e\u0441\u0442\u0430\u0442\u043e\u0447\u043d\u043e. \u0422\u043e\u0440\u043c\u043e\u0436\u0435\u043d\u0438\u0435 \u0431\u044b\u0441\u0442\u0440\u043e \u0443\u0442\u043e\u043c\u043b\u044f\u0435\u0442\u0441\u044f, \u043f\u043e\u044d\u0442\u043e\u043c\u0443, \u043a\u0430\u043a \u0442\u043e\u043b\u044c\u043a\u043e \u043e\u0441\u0442\u0430\u043d\u043e\u0432\u043a\u0438 \u0441\u0442\u0430\u043d\u043e\u0432\u044f\u0442\u0441\u044f \u0432\u044f\u043b\u044b\u043c\u0438 \u0438 \u043d\u0435\u0442\u043e\u0447\u043d\u044b\u043c\u0438, \u043d\u0430 \u0441\u0435\u0433\u043e\u0434\u043d\u044f \u043b\u0443\u0447\u0448\u0435 \u0437\u0430\u043a\u043e\u043d\u0447\u0438\u0442\u044c, \u0430 \u043d\u0435 \u043f\u0440\u043e\u0434\u0430\u0432\u043b\u0438\u0432\u0430\u0442\u044c \u0447\u0435\u0440\u0435\u0437 \u0441\u0438\u043b\u0443.",research:"\u041d\u0430\u0434\u0451\u0436\u043d\u043e \u0434\u043e\u043a\u0430\u0437\u0430\u043d\u043e \u043d\u0435\u043c\u043d\u043e\u0433\u043e\u0435: \u0432\u043d\u0443\u0442\u0440\u0438 \u0441\u0430\u043c\u043e\u0433\u043e \u0437\u0430\u0434\u0430\u043d\u0438\u044f \u0447\u0435\u043b\u043e\u0432\u0435\u043a \u043e\u0449\u0443\u0442\u0438\u043c\u043e \u0443\u0441\u043a\u043e\u0440\u044f\u0435\u0442\u0441\u044f \u0438 \u0441\u0442\u0430\u0431\u0438\u043b\u044c\u043d\u0435\u0435 \u0442\u043e\u0440\u043c\u043e\u0437\u0438\u0442, \u0430 \u0432\u0440\u0435\u043c\u044f \u0442\u043e\u0440\u043c\u043e\u0436\u0435\u043d\u0438\u044f (SSRT) \u2014 \u0445\u043e\u0440\u043e\u0448\u043e \u043f\u0440\u043e\u0432\u0435\u0440\u0435\u043d\u043d\u044b\u0439 \u043f\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c \u044d\u0442\u043e\u0439 \u0441\u043f\u043e\u0441\u043e\u0431\u043d\u043e\u0441\u0442\u0438. \u0421 \u0431\u043e\u043b\u0435\u0435 \u0448\u0438\u0440\u043e\u043a\u043e\u0439 \u043f\u043e\u043b\u044c\u0437\u043e\u0439 \u0432\u0441\u0451 \u0433\u043e\u0440\u0430\u0437\u0434\u043e \u0441\u043b\u0430\u0431\u0435\u0435. \u0414\u0430\u043d\u043d\u044b\u0435 \u043e \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0435 \u043d\u0430 \u043f\u043e\u0432\u0441\u0435\u0434\u043d\u0435\u0432\u043d\u044b\u0439 \u0441\u0430\u043c\u043e\u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044c \u0438 \u043e\u0431\u0449\u0443\u044e \u0438\u043c\u043f\u0443\u043b\u044c\u0441\u0438\u0432\u043d\u043e\u0441\u0442\u044c \u043f\u0440\u043e\u0442\u0438\u0432\u043e\u0440\u0435\u0447\u0438\u0432\u044b \u0438 \u0447\u0430\u0441\u0442\u043e \u043d\u0435 \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u044e\u0442\u0441\u044f, \u0430 \u043f\u0440\u0438\u043a\u043b\u0430\u0434\u043d\u044b\u0435 \u0432\u0435\u0440\u0441\u0438\u0438, \u0433\u0434\u0435 \u0441\u0442\u043e\u043f-\u0441\u0438\u0433\u043d\u0430\u043b \u043f\u0440\u0438\u0432\u044f\u0437\u0430\u043d \u043a \u0435\u0434\u0435 \u0438\u043b\u0438 \u0430\u043b\u043a\u043e\u0433\u043e\u043b\u044e, \u0441\u043f\u043e\u0441\u043e\u0431\u043d\u044b \u043d\u0435\u043d\u0430\u0434\u043e\u043b\u0433\u043e \u0441\u043d\u0438\u0437\u0438\u0442\u044c \u043f\u043e\u0442\u0440\u0435\u0431\u043b\u0435\u043d\u0438\u0435, \u043d\u043e \u044d\u0444\u0444\u0435\u043a\u0442 \u0441\u043a\u0440\u043e\u043c\u043d\u044b\u0439 \u0438 \u043e\u0431\u044b\u0447\u043d\u043e \u043d\u0435\u0434\u043e\u043b\u0433\u0438\u0439. \u0423\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043d\u0438\u044f, \u0447\u0442\u043e \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u0435 \u043d\u0430\u0434\u043e\u043b\u0433\u043e \u0443\u043a\u0440\u0435\u043f\u043b\u044f\u0435\u0442 \u0441\u0438\u043b\u0443 \u0432\u043e\u043b\u0438 \u0438\u043b\u0438 \u0437\u0430\u0449\u0438\u0449\u0430\u0435\u0442 \u043e\u0442 \u043a\u043e\u0433\u043d\u0438\u0442\u0438\u0432\u043d\u043e\u0433\u043e \u0441\u043f\u0430\u0434\u0430, \u043d\u0435 \u0434\u043e\u043a\u0430\u0437\u0430\u043d\u044b \u2014 \u043a \u0433\u0440\u043e\u043c\u043a\u0438\u043c \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f\u043c \u0441\u0442\u043e\u0438\u0442 \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u044c\u0441\u044f \u043e\u0441\u0442\u043e\u0440\u043e\u0436\u043d\u043e.",rec:"\u0412\u043e\u0441\u043f\u0440\u0438\u043d\u0438\u043c\u0430\u0439\u0442\u0435 \u044d\u0442\u043e \u043a\u0430\u043a \u0447\u0435\u0441\u0442\u043d\u0443\u044e \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0443 \u0442\u043e\u0440\u043c\u043e\u0437\u0430, \u0430 \u043d\u0435 \u0430\u043f\u0433\u0440\u0435\u0439\u0434 \u0441\u0438\u043b\u044b \u0432\u043e\u043b\u0438: \u0432\u044b\u043a\u043b\u0430\u0434\u044b\u0432\u0430\u0439\u0442\u0435\u0441\u044c \u043d\u0430 \u0441\u0438\u0433\u043d\u0430\u043b\u0430\u0445 \xab\u0438\u0434\u0438\xbb \u0438 \u0434\u0430\u0432\u0430\u0439\u0442\u0435 \u0441\u0442\u043e\u043f-\u0441\u0438\u0433\u043d\u0430\u043b\u0430\u043c \u0437\u0430\u0441\u0442\u0430\u0442\u044c \u0432\u0430\u0441 \u0432\u0440\u0430\u0441\u043f\u043b\u043e\u0445.",faq:[["\u042d\u0442\u043e \u043f\u043b\u043e\u0445\u043e, \u0435\u0441\u043b\u0438 \u044f \u0447\u0430\u0441\u0442\u043e \u043d\u0435 \u0443\u0441\u043f\u0435\u0432\u0430\u044e \u043e\u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u044c\u0441\u044f?","\u041d\u0435\u0442, \u0442\u0430\u043a \u0438 \u0437\u0430\u0434\u0443\u043c\u0430\u043d\u043e. \u0425\u043e\u0440\u043e\u0448\u0430\u044f \u0432\u0435\u0440\u0441\u0438\u044f \u043d\u0430\u043c\u0435\u0440\u0435\u043d\u043d\u043e \u0434\u0435\u0440\u0436\u0438\u0442 \u0432\u0430\u0441 \u0443 \u043e\u0442\u043c\u0435\u0442\u043a\u0438 \u043e\u043a\u043e\u043b\u043e 50 \u043f\u0440\u043e\u0446\u0435\u043d\u0442\u043e\u0432 \u0443\u0434\u0430\u0447\u043d\u044b\u0445 \u043e\u0441\u0442\u0430\u043d\u043e\u0432\u043e\u043a, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u043f\u0440\u043e\u043c\u0430\u0445\u0438 \u043f\u0440\u0438\u043c\u0435\u0440\u043d\u043e \u0432 \u043f\u043e\u043b\u043e\u0432\u0438\u043d\u0435 \u0441\u0442\u043e\u043f-\u043f\u043e\u043f\u044b\u0442\u043e\u043a \u043e\u0437\u043d\u0430\u0447\u0430\u044e\u0442, \u0447\u0442\u043e \u0441\u043b\u043e\u0436\u043d\u043e\u0441\u0442\u044c \u043d\u0430\u0441\u0442\u0440\u043e\u0435\u043d\u0430 \u0432\u0435\u0440\u043d\u043e, \u0430 \u043d\u0435 \u0447\u0442\u043e \u0432\u044b \u0434\u0435\u043b\u0430\u0435\u0442\u0435 \u0447\u0442\u043e-\u0442\u043e \u043d\u0435 \u0442\u0430\u043a."],["\u041c\u043e\u0436\u0435\u0442, \u043f\u043e\u0434\u043e\u0436\u0434\u0430\u0442\u044c \u043c\u0433\u043d\u043e\u0432\u0435\u043d\u0438\u0435 \u043f\u0435\u0440\u0435\u0434 \u043e\u0442\u0432\u0435\u0442\u043e\u043c, \u0447\u0442\u043e\u0431\u044b \u0443\u0441\u043f\u0435\u0442\u044c \u043d\u0430 \u0441\u0442\u043e\u043f-\u0441\u0438\u0433\u043d\u0430\u043b?","\u041d\u0435\u0442, \u044d\u0442\u043e \u0443\u0431\u0438\u0432\u0430\u0435\u0442 \u0432\u0435\u0441\u044c \u0441\u043c\u044b\u0441\u043b \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u044f. \u041d\u0430\u043c\u0435\u0440\u0435\u043d\u043d\u0430\u044f \u0437\u0430\u0434\u0435\u0440\u0436\u043a\u0430 \u043f\u043e\u0437\u0432\u043e\u043b\u044f\u0435\u0442 \xab\u0432\u044b\u0438\u0433\u0440\u044b\u0432\u0430\u0442\u044c\xbb \u0437\u0430 \u0441\u0447\u0451\u0442 \u043f\u0440\u043e\u043c\u0435\u0434\u043b\u0435\u043d\u0438\u044f, \u0438 \u0442\u043e\u0433\u0434\u0430 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442 \u0442\u0435\u0440\u044f\u0435\u0442 \u0446\u0435\u043d\u043d\u043e\u0441\u0442\u044c. \u0411\u044b\u0441\u0442\u0440\u043e \u0440\u0435\u0430\u0433\u0438\u0440\u0443\u0439\u0442\u0435 \u043d\u0430 \u0441\u0438\u0433\u043d\u0430\u043b \xab\u0438\u0434\u0438\xbb \u0438 \u0442\u043e\u0440\u043c\u043e\u0437\u0438\u0442\u0435 \u0442\u043e\u043b\u044c\u043a\u043e \u0442\u043e\u0433\u0434\u0430, \u043a\u043e\u0433\u0434\u0430 \u0441\u0442\u043e\u043f-\u0441\u0438\u0433\u043d\u0430\u043b \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043b\u044c\u043d\u043e \u043f\u043e\u044f\u0432\u0438\u043b\u0441\u044f."],["\u0421\u0442\u0430\u043d\u0435\u0442 \u043b\u0438 \u0431\u043b\u0430\u0433\u043e\u0434\u0430\u0440\u044f \u044d\u0442\u043e\u043c\u0443 \u043c\u0435\u043d\u044c\u0448\u0435 \u0438\u043c\u043f\u0443\u043b\u044c\u0441\u0438\u0432\u043d\u043e\u0441\u0442\u0438 \u0432 \u0436\u0438\u0437\u043d\u0438?","\u0412\u043d\u0443\u0442\u0440\u0438 \u0437\u0430\u0434\u0430\u043d\u0438\u044f \u0432\u044b \u0442\u043e\u0447\u043d\u043e \u043d\u0430\u0447\u043d\u0451\u0442\u0435 \u0442\u043e\u0440\u043c\u043e\u0437\u0438\u0442\u044c \u043b\u0443\u0447\u0448\u0435, \u043d\u043e \u043f\u0435\u0440\u0435\u043d\u043e\u0441 \u043d\u0430 \u043f\u043e\u0432\u0441\u0435\u0434\u043d\u0435\u0432\u043d\u044b\u0439 \u0441\u0430\u043c\u043e\u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044c \u043d\u0435 \u0433\u0430\u0440\u0430\u043d\u0442\u0438\u0440\u043e\u0432\u0430\u043d, \u0438 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u044f \u043f\u0440\u043e\u0442\u0438\u0432\u043e\u0440\u0435\u0447\u0438\u0432\u044b. \u0418\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0439\u0442\u0435 \u044d\u0442\u043e \u043a\u0430\u043a \u0442\u043e\u0447\u0435\u0447\u043d\u0443\u044e \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0443 \u0442\u043e\u0440\u043c\u043e\u0437\u043d\u043e\u0433\u043e \u0440\u0435\u0444\u043b\u0435\u043a\u0441\u0430, \u0430 \u043d\u0435 \u043a\u0430\u043a \u0432\u0435\u0440\u043d\u043e\u0435 \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043e \u043e\u0442 \u0438\u043c\u043f\u0443\u043b\u044c\u0441\u0438\u0432\u043d\u043e\u0441\u0442\u0438."]],variants:"\u0411\u043b\u0438\u0437\u043a\u0438\u0435 \u0440\u043e\u0434\u0441\u0442\u0432\u0435\u043d\u043d\u0438\u043a\u0438 \u2014 \u0437\u0430\u0434\u0430\u0447\u0430 go/no-go, \u0433\u0434\u0435 \u0440\u0435\u0430\u043a\u0446\u0438\u044e \u043d\u0435 \u043e\u0442\u043c\u0435\u043d\u044f\u044e\u0442 \u043d\u0430 \u043b\u0435\u0442\u0443, \u0430 \u043f\u0440\u043e\u0441\u0442\u043e \u043d\u0435 \u0437\u0430\u043f\u0443\u0441\u043a\u0430\u044e\u0442 \u0432\u043e\u0432\u0441\u0435. \u0421\u0430\u043c \u0441\u0442\u043e\u043f-\u0441\u0438\u0433\u043d\u0430\u043b \u0431\u044b\u0432\u0430\u0435\u0442 \u0437\u0432\u0443\u043a\u043e\u043c, \u0441\u043c\u0435\u043d\u043e\u0439 \u0446\u0432\u0435\u0442\u0430 \u0438\u043b\u0438 \u0434\u043e\u043f\u043e\u043b\u043d\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u043c \u0441\u0438\u043c\u0432\u043e\u043b\u043e\u043c, \u0430 \u043f\u0440\u0438\u043a\u043b\u0430\u0434\u043d\u044b\u0435 \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u044b \u043f\u0440\u0438\u0432\u044f\u0437\u044b\u0432\u0430\u044e\u0442 \u043e\u0441\u0442\u0430\u043d\u043e\u0432\u043a\u0443 \u043a \u043a\u043e\u043d\u043a\u0440\u0435\u0442\u043d\u044b\u043c \u043a\u0430\u0440\u0442\u0438\u043d\u043a\u0430\u043c \u2014 \u043d\u0430\u043f\u0440\u0438\u043c\u0435\u0440, \u043a \u0441\u043e\u0431\u043b\u0430\u0437\u043d\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u0439 \u0435\u0434\u0435 \u0438\u043b\u0438 \u0430\u043b\u043a\u043e\u0433\u043e\u043b\u044e \u2014 \u0447\u0442\u043e\u0431\u044b \u0438\u0437\u0443\u0447\u0430\u0442\u044c \u0438 \u043a\u043e\u0440\u0440\u0435\u043a\u0442\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u0440\u0435\u0430\u043b\u044c\u043d\u044b\u0435 \u0438\u043c\u043f\u0443\u043b\u044c\u0441\u044b."},en:{about:"Stop-Signal: Inhibition trains the brakes on an action you have already begun. You respond as fast as you can to a steady stream of go cues (say, tap left or right for an arrow), but on a minority of trials a stop signal appears a fraction of a second later, and on those you must abort the response you were already launching.",benefit:"It targets response inhibition, the executive-control ability to cancel an action mid-flight. This is the same machinery you lean on to hold back a reflex, catch yourself before a slip, or stop reaching for something on impulse.",history:"The idea of using a delayed signal to cancel a reaction-time response goes back to Lappin and Eriksen in 1966. It became a precise measurement tool in 1984 when Logan and Cowan formalised the horse-race model, and from the 1990s onward it spread into clinical and neuroscience work on ADHD, addiction, and impulsivity, and later into consumer brain-training apps.",creator:"There is no single inventor of the underlying idea. An early visual stop-signal experiment was published by Joseph Lappin and Charles Eriksen in 1966, and the modern task with its measurable inhibition time was established by Gordon Logan and William Cowan in 1984 with the paper 'On the ability to inhibit simple and choice reaction time responses.'",methods:"Commit fully to going fast on every trial, because deliberately slowing down to catch the stop signal is cheating and ruins the measurement. Keep your finger or attention poised but neutral, react to the stop signal rather than predicting it, and let the difficulty adapt so you are succeeding on roughly half the stop trials, which is where the work actually happens.",duration:"Short, frequent sessions beat marathons: about 10 to 15 minutes, three or four times a week, is plenty. Inhibition fatigues quickly, so once your stopping gets sloppy and slow, stop for the day rather than pushing through.",research:"What is solidly shown is narrow: people get measurably faster and more reliable at stopping within this task, and the stop-signal reaction time is a well-validated index of inhibition. Broader payoffs are much weaker. Evidence that training transfers to everyday self-control or general impulsivity is mixed and often fails to hold up, and applied versions that pair stop signals with food or alcohol cues can nudge intake down briefly but show modest, frequently short-lived effects. Claims that it lastingly raises self-discipline or prevents cognitive decline are not established, so treat the big promises with caution.",rec:"Treat it as honest brake practice, not a willpower upgrade: go all-out on the go trials and let the stop signals catch you off guard.",faq:[["Is it bad if I fail to stop a lot?","No, that is expected. A good version keeps you near a 50 percent stopping rate on purpose, so failing about half the stop trials means it is calibrated correctly, not that you are doing it wrong."],["Should I wait a beat before responding so I can catch the stop signal?","No, that defeats the whole exercise. Slowing down on purpose lets you 'win' by stalling, which makes the score meaningless. React quickly to go cues and only brake when the stop signal actually appears."],["Will this make me less impulsive in real life?","It will reliably improve your stopping inside the task, but carryover to everyday impulse control is uncertain and the research is mixed. Use it as focused training for the braking reflex, not as a guaranteed fix for impulsivity."]],variants:"Close relatives include the go/no-go task, where you withhold a response that was never started rather than cancelling one in flight. The stop signal itself varies between a tone, a colour change, or an extra symbol, and applied versions attach the stop to specific images such as tempting foods or alcohol to study and shape real-world urges."},es:{about:"Stop-Signal: Inhibici\xf3n entrena el freno de una acci\xf3n que ya has empezado. Respondes lo m\xe1s r\xe1pido que puedes a un flujo constante de se\xf1ales de \"adelante\" (por ejemplo, pulsar a la izquierda o a la derecha seg\xfan una flecha), pero en una minor\xeda de ensayos aparece una se\xf1al de alto una fracci\xf3n de segundo despu\xe9s, y ante ellas debes abortar la respuesta que ya estabas lanzando.",benefit:"Apunta a la inhibici\xf3n de la respuesta, la capacidad de control ejecutivo para cancelar una acci\xf3n en pleno vuelo. Es la misma maquinaria en la que te apoyas para contener un reflejo, frenarte antes de un desliz o dejar de alargar la mano hacia algo por impulso.",history:"La idea de usar una se\xf1al retardada para cancelar una respuesta de tiempo de reacci\xf3n se remonta a Lappin y Eriksen en 1966. Se convirti\xf3 en una herramienta de medici\xf3n precisa en 1984, cuando Logan y Cowan formalizaron el modelo de carrera de caballos, y a partir de los a\xf1os noventa se extendi\xf3 al trabajo cl\xednico y neurocient\xedfico sobre el TDAH, las adicciones y la impulsividad, y m\xe1s tarde a las aplicaciones comerciales de entrenamiento cerebral.",creator:"No hay un \xfanico inventor de la idea de fondo. Un experimento temprano de se\xf1al de alto visual lo publicaron Joseph Lappin y Charles Eriksen en 1966, y la tarea moderna, con su tiempo de inhibici\xf3n medible, la establecieron Gordon Logan y William Cowan en 1984 con el art\xedculo 'On the ability to inhibit simple and choice reaction time responses.'",methods:"Comprom\xe9tete del todo a ir r\xe1pido en cada ensayo, porque frenar a prop\xf3sito para atrapar la se\xf1al de alto es hacer trampa y arruina la medici\xf3n. Mant\xe9n el dedo o la atenci\xf3n preparados pero neutros, reacciona a la se\xf1al de alto en vez de anticiparla, y deja que la dificultad se ajuste para que aciertes en torno a la mitad de los ensayos de alto, que es donde de verdad ocurre el trabajo.",duration:"Las sesiones cortas y frecuentes superan a los maratones: unos 10 a 15 minutos, tres o cuatro veces por semana, bastan. La inhibici\xf3n se fatiga deprisa, as\xed que en cuanto tu frenado se vuelva descuidado y lento, d\xe9jalo por hoy en lugar de forzar.",research:"Lo que est\xe1 s\xf3lidamente demostrado es limitado: la gente se vuelve mensurablemente m\xe1s r\xe1pida y fiable al frenar dentro de esta tarea, y el tiempo de reacci\xf3n de la se\xf1al de alto es un \xedndice de inhibici\xf3n bien validado. Los beneficios m\xe1s amplios son mucho m\xe1s d\xe9biles. La evidencia de que el entrenamiento se transfiere al autocontrol cotidiano o a la impulsividad general es dispar y a menudo no se sostiene, y las versiones aplicadas que asocian se\xf1ales de alto a comida o alcohol pueden reducir brevemente el consumo, pero muestran efectos modestos y con frecuencia pasajeros. Las afirmaciones de que aumenta de forma duradera la autodisciplina o previene el deterioro cognitivo no est\xe1n demostradas, as\xed que toma con cautela las grandes promesas.",rec:"T\xf3malo como un entrenamiento honesto de frenado, no como una mejora de la fuerza de voluntad: ve a tope en los ensayos de \"adelante\" y deja que las se\xf1ales de alto te pillen desprevenido.",faq:[["\xbfEs malo si fallo el frenado muchas veces?","No, es lo esperable. Una buena versi\xf3n te mantiene cerca de una tasa de frenado del 50 por ciento a prop\xf3sito, as\xed que fallar alrededor de la mitad de los ensayos de alto significa que est\xe1 bien calibrada, no que lo est\xe9s haciendo mal."],["\xbfDeber\xeda esperar un instante antes de responder para poder atrapar la se\xf1al de alto?","No, eso echa a perder todo el ejercicio. Frenar a prop\xf3sito te permite 'ganar' demor\xe1ndote, lo que hace que la puntuaci\xf3n pierda todo sentido. Reacciona r\xe1pido a las se\xf1ales de \"adelante\" y frena solo cuando la se\xf1al de alto aparezca de verdad."],["\xbfEsto me har\xe1 menos impulsivo en la vida real?","Mejorar\xe1 de forma fiable tu frenado dentro de la tarea, pero el traslado al control de impulsos cotidiano es incierto y la investigaci\xf3n es dispar. \xdasalo como entrenamiento centrado del reflejo de frenado, no como una soluci\xf3n garantizada para la impulsividad."]],variants:"Entre sus parientes cercanos est\xe1 la tarea go/no-go, en la que retienes una respuesta que nunca lleg\xf3 a iniciarse en lugar de cancelar una en pleno vuelo. La propia se\xf1al de alto var\xeda entre un tono, un cambio de color o un s\xedmbolo a\xf1adido, y las versiones aplicadas asocian el alto a im\xe1genes concretas, como alimentos tentadores o alcohol, para estudiar y moldear impulsos del mundo real."},de:{about:"Stopp-Signal: Inhibition trainiert die Bremse f\xfcr eine Handlung, die du bereits begonnen hast. Du reagierst so schnell wie m\xf6glich auf einen stetigen Strom von Go-Hinweisen (etwa: tippe links oder rechts je nach Pfeil), doch bei einem Teil der Durchg\xe4nge erscheint einen Sekundenbruchteil sp\xe4ter ein Stopp-Signal, und dann musst du die gerade angesto\xdfene Reaktion abbrechen.",benefit:"Im Zentrum steht die Reaktionshemmung, die exekutive F\xe4higkeit, eine Handlung mitten in der Ausf\xfchrung abzubrechen. Das ist dieselbe Maschinerie, auf die du dich st\xfctzt, wenn du einen Reflex zur\xfcckh\xe4ltst, dich kurz vor einem Patzer abf\xe4ngst oder es bleiben l\xe4sst, impulsiv nach etwas zu greifen.",history:"Die Idee, ein verz\xf6gertes Signal zum Abbruch einer Reaktionszeit-Antwort zu nutzen, geht auf Lappin und Eriksen im Jahr 1966 zur\xfcck. Zu einem pr\xe4zisen Messinstrument wurde sie 1984, als Logan und Cowan das Wettrennen-Modell formalisierten, und ab den 1990er-Jahren verbreitete sie sich in der klinischen und neurowissenschaftlichen Forschung zu ADHS, Sucht und Impulsivit\xe4t und sp\xe4ter in kommerzielle Gehirntrainings-Apps.",creator:"F\xfcr die zugrunde liegende Idee gibt es keinen einzelnen Erfinder. Ein fr\xfches visuelles Stopp-Signal-Experiment ver\xf6ffentlichten Joseph Lappin und Charles Eriksen 1966, und die moderne Aufgabe mit ihrer messbaren Hemmungszeit etablierten Gordon Logan und William Cowan 1984 mit der Arbeit 'On the ability to inhibit simple and choice reaction time responses'.",methods:"Gib dich bei jedem Durchgang voll dem schnellen Reagieren hin, denn bewusst langsamer zu werden, um das Stopp-Signal abzufangen, ist Schummeln und ruiniert die Messung. Halte Finger und Aufmerksamkeit bereit, aber neutral, reagiere auf das Stopp-Signal, statt es vorherzusehen, und lass die Schwierigkeit sich anpassen, sodass dir etwa die H\xe4lfte der Stopp-Durchg\xe4nge gelingt, denn genau dort findet die eigentliche Arbeit statt.",duration:"Kurze, h\xe4ufige Sitzungen schlagen Marathons: rund 10 bis 15 Minuten, drei- oder viermal die Woche, reichen v\xf6llig. Die Hemmung erm\xfcdet rasch, also h\xf6r f\xfcr den Tag auf, sobald dein Stoppen schlampig und langsam wird, statt es zu erzwingen.",research:"Solide belegt ist nur ein enger Bereich: Menschen werden innerhalb dieser Aufgabe messbar schneller und zuverl\xe4ssiger im Stoppen, und die Stopp-Signal-Reaktionszeit ist ein gut validierter Index der Hemmung. Der weitere Nutzen ist deutlich schw\xe4cher belegt. Hinweise darauf, dass sich das Training auf die allt\xe4gliche Selbstkontrolle oder allgemeine Impulsivit\xe4t \xfcbertr\xe4gt, sind gemischt und halten oft nicht stand, und angewandte Versionen, die Stopp-Signale mit Nahrungs- oder Alkoholreizen koppeln, k\xf6nnen den Konsum kurzfristig etwas senken, zeigen aber bescheidene und h\xe4ufig kurzlebige Effekte. Behauptungen, es hebe dauerhaft die Selbstdisziplin oder beuge geistigem Abbau vor, sind nicht gesichert, also behandle die gro\xdfen Versprechen mit Vorsicht.",rec:"Betrachte es als ehrliches Bremstraining, nicht als Willenskraft-Upgrade: Geh bei den Go-Durchg\xe4ngen volle Pulle und lass dich von den Stopp-Signalen \xfcberrumpeln.",faq:[["Ist es schlimm, wenn ich oft nicht rechtzeitig stoppe?","Nein, das ist zu erwarten. Eine gute Version h\xe4lt dich absichtlich nahe einer Stoppquote von 50 Prozent, das Scheitern an etwa der H\xe4lfte der Stopp-Durchg\xe4nge bedeutet also, dass sie korrekt kalibriert ist, nicht dass du etwas falsch machst."],["Soll ich einen Moment warten, bevor ich reagiere, um das Stopp-Signal abzufangen?","Nein, das hebelt die ganze \xdcbung aus. Absichtliches Verz\xf6gern l\xe4sst dich durch Hinhalten 'gewinnen', was die Wertung sinnlos macht. Reagiere schnell auf die Go-Hinweise und bremse nur, wenn das Stopp-Signal tats\xe4chlich erscheint."],["Werde ich dadurch im echten Leben weniger impulsiv?","Es verbessert zuverl\xe4ssig dein Stoppen innerhalb der Aufgabe, aber die \xdcbertragung auf die allt\xe4gliche Impulskontrolle ist ungewiss und die Forschung uneinheitlich. Nutze es als gezieltes Training f\xfcr den Bremsreflex, nicht als garantierte L\xf6sung gegen Impulsivit\xe4t."]],variants:"Nahe Verwandte sind die Go/No-Go-Aufgabe, bei der du eine nie begonnene Reaktion zur\xfcckh\xe4ltst, statt eine laufende abzubrechen. Das Stopp-Signal selbst variiert zwischen einem Ton, einem Farbwechsel oder einem zus\xe4tzlichen Symbol, und angewandte Versionen kn\xfcpfen das Stopp an bestimmte Bilder wie verlockende Speisen oder Alkohol, um reale Gel\xfcste zu untersuchen und zu formen."},pt:{about:"Sinal de Parada: Inibi\xe7\xe3o treina os freios de uma a\xe7\xe3o que voc\xea j\xe1 come\xe7ou. Voc\xea responde o mais r\xe1pido que consegue a um fluxo constante de pistas de \"vai\" (por exemplo, tocar \xe0 esquerda ou \xe0 direita conforme uma seta), mas numa minoria das tentativas surge um sinal de parada uma fra\xe7\xe3o de segundo depois, e nessas voc\xea precisa abortar a resposta que j\xe1 estava disparando.",benefit:"Mira a inibi\xe7\xe3o da resposta, a capacidade de controle executivo de cancelar uma a\xe7\xe3o em pleno voo. \xc9 a mesma maquinaria de que voc\xea depende para conter um reflexo, se segurar antes de um deslize ou parar de estender a m\xe3o por impulso.",history:"A ideia de usar um sinal atrasado para cancelar uma resposta de tempo de rea\xe7\xe3o remonta a Lappin e Eriksen, em 1966. Tornou-se uma ferramenta de medi\xe7\xe3o precisa em 1984, quando Logan e Cowan formalizaram o modelo de corrida de cavalos, e a partir dos anos 1990 se espalhou para o trabalho cl\xednico e neurocient\xedfico sobre TDAH, depend\xeancia e impulsividade, e mais tarde para os aplicativos comerciais de treino cerebral.",creator:"N\xe3o h\xe1 um \xfanico inventor da ideia subjacente. Um experimento visual precoce de sinal de parada foi publicado por Joseph Lappin e Charles Eriksen em 1966, e a tarefa moderna, com o seu tempo de inibi\xe7\xe3o mensur\xe1vel, foi estabelecida por Gordon Logan e William Cowan em 1984, com o artigo 'On the ability to inhibit simple and choice reaction time responses.'",methods:"Comprometa-se totalmente a ir r\xe1pido em cada tentativa, porque desacelerar de prop\xf3sito para pegar o sinal de parada \xe9 trapa\xe7a e arru\xedna a medi\xe7\xe3o. Mantenha o dedo ou a aten\xe7\xe3o prontos mas neutros, reaja ao sinal de parada em vez de antecip\xe1-lo, e deixe a dificuldade se ajustar para que voc\xea acerte mais ou menos metade das tentativas de parada, que \xe9 onde o trabalho de fato acontece.",duration:"Sess\xf5es curtas e frequentes vencem maratonas: cerca de 10 a 15 minutos, tr\xeas ou quatro vezes por semana, j\xe1 basta. A inibi\xe7\xe3o se cansa r\xe1pido, ent\xe3o assim que a sua frenagem ficar desleixada e lenta, pare por hoje em vez de insistir.",research:"O que est\xe1 solidamente demonstrado \xe9 limitado: as pessoas ficam mensuravelmente mais r\xe1pidas e mais confi\xe1veis em parar dentro desta tarefa, e o tempo de rea\xe7\xe3o ao sinal de parada \xe9 um \xedndice de inibi\xe7\xe3o bem validado. Os ganhos mais amplos s\xe3o bem mais fr\xe1geis. A evid\xeancia de que o treino se transfere para o autocontrole do dia a dia ou para a impulsividade geral \xe9 mista e muitas vezes n\xe3o se sustenta, e as vers\xf5es aplicadas que associam sinais de parada a pistas de comida ou \xe1lcool podem reduzir o consumo brevemente, mas mostram efeitos modestos e com frequ\xeancia passageiros. Afirma\xe7\xf5es de que isso eleva de forma duradoura a autodisciplina ou previne o decl\xednio cognitivo n\xe3o est\xe3o estabelecidas, ent\xe3o encare as grandes promessas com cautela.",rec:"Trate como pr\xe1tica honesta de freio, n\xe3o como upgrade de for\xe7a de vontade: v\xe1 com tudo nas tentativas de \"vai\" e deixe os sinais de parada te pegarem desprevenido.",faq:[["\xc9 ruim se eu falhar em parar muitas vezes?","N\xe3o, isso \xe9 esperado. Uma boa vers\xe3o mant\xe9m voc\xea perto de uma taxa de parada de 50 por cento de prop\xf3sito, ent\xe3o falhar em cerca de metade das tentativas de parada significa que est\xe1 calibrada corretamente, n\xe3o que voc\xea est\xe1 fazendo errado."],["Devo esperar um instante antes de responder para conseguir pegar o sinal de parada?","N\xe3o, isso anula o exerc\xedcio inteiro. Desacelerar de prop\xf3sito permite que voc\xea \"ven\xe7a\" enrolando, o que torna a pontua\xe7\xe3o sem sentido. Reaja r\xe1pido \xe0s pistas de \"vai\" e s\xf3 freie quando o sinal de parada realmente aparecer."],["Isso vai me deixar menos impulsivo na vida real?","Vai melhorar de forma confi\xe1vel a sua frenagem dentro da tarefa, mas a transfer\xeancia para o controle de impulsos do dia a dia \xe9 incerta e a pesquisa \xe9 mista. Use como treino focado do reflexo de frenagem, n\xe3o como solu\xe7\xe3o garantida para a impulsividade."]],variants:"Parentes pr\xf3ximos incluem a tarefa vai/n\xe3o vai, em que voc\xea cont\xe9m uma resposta que nunca chegou a come\xe7ar, em vez de cancelar uma j\xe1 em movimento. O pr\xf3prio sinal de parada varia entre um tom, uma mudan\xe7a de cor ou um s\xedmbolo extra, e as vers\xf5es aplicadas atrelam a parada a imagens espec\xedficas, como comidas tentadoras ou \xe1lcool, para estudar e moldar impulsos do mundo real."},hi:{about:"Stop-Signal: Inhibition \u0909\u0938 \u0915\u094d\u0930\u093f\u092f\u093e \u092a\u0930 \u092c\u094d\u0930\u0947\u0915 \u0932\u0917\u093e\u0928\u093e \u0938\u093e\u0927\u0924\u093e \u0939\u0948 \u091c\u093f\u0938\u0947 \u0906\u092a \u092a\u0939\u0932\u0947 \u0939\u0940 \u0936\u0941\u0930\u0942 \u0915\u0930 \u091a\u0941\u0915\u0947 \u0939\u0948\u0902\u0964 go \u0938\u0902\u0915\u0947\u0924\u094b\u0902 \u0915\u0940 \u090f\u0915 \u0938\u094d\u0925\u093f\u0930 \u0927\u093e\u0930\u093e \u092a\u0930 \u0906\u092a \u091c\u093f\u0924\u0928\u0940 \u091c\u0932\u094d\u0926\u0940 \u0939\u094b \u0938\u0915\u0947 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0926\u0947\u0924\u0947 \u0939\u0948\u0902 (\u091c\u0948\u0938\u0947 \u0924\u0940\u0930 \u0915\u0947 \u0939\u093f\u0938\u093e\u092c \u0938\u0947 \u092c\u093e\u090f\u0901 \u092f\u093e \u0926\u093e\u090f\u0901 \u091f\u0948\u092a \u0915\u0930\u0928\u093e), \u092a\u0930 \u0925\u094b\u0921\u093c\u0947-\u0938\u0947 \u091f\u094d\u0930\u093e\u092f\u0932\u094b\u0902 \u092e\u0947\u0902 \u090f\u0915 \u0938\u0947\u0915\u0902\u0921 \u0915\u0947 \u0905\u0902\u0936 \u092d\u0930 \u092c\u093e\u0926 \u090f\u0915 stop \u0938\u0902\u0915\u0947\u0924 \u0906 \u091c\u093e\u0924\u093e \u0939\u0948, \u0914\u0930 \u0909\u0928 \u092a\u0930 \u0906\u092a\u0915\u094b \u0935\u0939 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0930\u094b\u0915 \u0926\u0947\u0928\u0940 \u0939\u094b\u0924\u0940 \u0939\u0948 \u091c\u094b \u0906\u092a \u0936\u0941\u0930\u0942 \u0915\u0930 \u0939\u0940 \u091a\u0941\u0915\u0947 \u0925\u0947\u0964",benefit:"\u092f\u0939 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0928\u093f\u0930\u094b\u0927 (response inhibition) \u0915\u094b \u0928\u093f\u0936\u093e\u0928\u093e \u092c\u0928\u093e\u0924\u093e \u0939\u0948 \u2014 \u092f\u093e\u0928\u0940 \u0915\u093f\u0938\u0940 \u0915\u094d\u0930\u093f\u092f\u093e \u0915\u094b \u092c\u0940\u091a \u092e\u0947\u0902 \u0939\u0940 \u0930\u0926\u094d\u0926 \u0915\u0930 \u0926\u0947\u0928\u0947 \u0915\u0940 \u0915\u093e\u0930\u094d\u092f\u0915\u093e\u0930\u0940-\u0928\u093f\u092f\u0902\u0924\u094d\u0930\u0923 \u0915\u094d\u0937\u092e\u0924\u093e\u0964 \u092f\u0939 \u0935\u0939\u0940 \u0924\u0902\u0924\u094d\u0930 \u0939\u0948 \u091c\u093f\u0938\u0915\u0947 \u0938\u0939\u093e\u0930\u0947 \u0906\u092a \u0915\u094b\u0908 \u092a\u0932\u091f\u0935\u093e\u0930 \u0930\u094b\u0915\u0924\u0947 \u0939\u0948\u0902, \u0915\u093f\u0938\u0940 \u091a\u0942\u0915 \u0938\u0947 \u092a\u0939\u0932\u0947 \u0916\u093c\u0941\u0926 \u0915\u094b \u0938\u0901\u092d\u093e\u0932\u0924\u0947 \u0939\u0948\u0902, \u092f\u093e \u0906\u0935\u0947\u0917 \u092e\u0947\u0902 \u0915\u093f\u0938\u0940 \u091a\u0940\u091c\u093c \u0915\u0940 \u0913\u0930 \u092c\u0922\u093c\u0924\u0947 \u0939\u093e\u0925 \u0915\u094b \u0930\u094b\u0915 \u0932\u0947\u0924\u0947 \u0939\u0948\u0902\u0964",history:"\u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0938\u092e\u092f \u0935\u093e\u0932\u0940 \u0915\u093f\u0938\u0940 \u0915\u094d\u0930\u093f\u092f\u093e \u0915\u094b \u0930\u0926\u094d\u0926 \u0915\u0930\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u090f\u0915 \u0926\u0947\u0930 \u0938\u0947 \u0906\u0928\u0947 \u0935\u093e\u0932\u0947 \u0938\u0902\u0915\u0947\u0924 \u0915\u093e \u0935\u093f\u091a\u093e\u0930 1966 \u092e\u0947\u0902 Lappin \u0914\u0930 Eriksen \u0924\u0915 \u091c\u093e\u0924\u093e \u0939\u0948\u0964 \u092f\u0939 1984 \u092e\u0947\u0902 \u090f\u0915 \u0938\u091f\u0940\u0915 \u092e\u093e\u092a\u0928-\u0914\u091c\u093c\u093e\u0930 \u092c\u0928\u093e, \u091c\u092c Logan \u0914\u0930 Cowan \u0928\u0947 horse-race \u092e\u0949\u0921\u0932 \u0915\u094b \u0914\u092a\u091a\u093e\u0930\u093f\u0915 \u0930\u0942\u092a \u0926\u093f\u092f\u093e; \u0914\u0930 1990 \u0915\u0947 \u0926\u0936\u0915 \u0938\u0947 \u0906\u0917\u0947 \u092f\u0939 ADHD, \u0928\u0936\u0947 \u0914\u0930 \u0906\u0935\u0947\u0917 \u092a\u0930 \u0915\u094d\u0932\u093f\u0928\u093f\u0915\u0932 \u0924\u0925\u093e \u0924\u0902\u0924\u094d\u0930\u093f\u0915\u093e-\u0935\u093f\u091c\u094d\u091e\u093e\u0928 \u0915\u0947 \u0915\u093e\u092e \u092e\u0947\u0902, \u0914\u0930 \u092c\u093e\u0926 \u092e\u0947\u0902 \u0909\u092a\u092d\u094b\u0915\u094d\u0924\u093e \u092c\u094d\u0930\u0947\u0928-\u091f\u094d\u0930\u0947\u0928\u093f\u0902\u0917 \u0910\u092a\u094d\u0938 \u092e\u0947\u0902 \u092b\u0948\u0932 \u0917\u092f\u093e\u0964",creator:"\u092e\u0942\u0932 \u0935\u093f\u091a\u093e\u0930 \u0915\u093e \u0915\u094b\u0908 \u090f\u0915 \u0906\u0935\u093f\u0937\u094d\u0915\u093e\u0930\u0915 \u0928\u0939\u0940\u0902 \u0939\u0948\u0964 \u090f\u0915 \u0936\u0941\u0930\u0941\u0906\u0924\u0940 \u0926\u0943\u0936\u094d\u092f stop-signal \u092a\u094d\u0930\u092f\u094b\u0917 1966 \u092e\u0947\u0902 Joseph Lappin \u0914\u0930 Charles Eriksen \u0928\u0947 \u092a\u094d\u0930\u0915\u093e\u0936\u093f\u0924 \u0915\u093f\u092f\u093e, \u0914\u0930 \u0905\u092a\u0928\u0947 \u092e\u093e\u092a\u0947 \u091c\u093e \u0938\u0915\u0928\u0947 \u0935\u093e\u0932\u0947 \u0928\u093f\u0930\u094b\u0927-\u0938\u092e\u092f \u0915\u0947 \u0938\u093e\u0925 \u0906\u0927\u0941\u0928\u093f\u0915 \u091f\u093e\u0938\u094d\u0915 \u0915\u094b 1984 \u092e\u0947\u0902 Gordon Logan \u0914\u0930 William Cowan \u0928\u0947 \u0938\u094d\u0925\u093e\u092a\u093f\u0924 \u0915\u093f\u092f\u093e \u2014 \u0909\u0928\u0915\u0947 \u092a\u0930\u094d\u091a\u0947 'On the ability to inhibit simple and choice reaction time responses' \u0915\u0947 \u091c\u093c\u0930\u093f\u090f\u0964",methods:"\u0939\u0930 \u091f\u094d\u0930\u093e\u092f\u0932 \u092a\u0930 \u092a\u0942\u0930\u0940 \u0924\u0930\u0939 \u0924\u0947\u091c\u093c \u091c\u093e\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0924\u0948\u092f\u093e\u0930 \u0930\u0939\u0947\u0902, \u0915\u094d\u092f\u094b\u0902\u0915\u093f stop \u0938\u0902\u0915\u0947\u0924 \u092a\u0915\u0921\u093c\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u091c\u093e\u0928-\u092c\u0942\u091d\u0915\u0930 \u0927\u0940\u092e\u0947 \u0939\u094b\u0928\u093e \u0927\u094b\u0916\u093e \u0939\u0948 \u0914\u0930 \u092e\u093e\u092a \u0915\u094b \u092c\u0930\u094d\u092c\u093e\u0926 \u0915\u0930 \u0926\u0947\u0924\u093e \u0939\u0948\u0964 \u0905\u092a\u0928\u0940 \u0909\u0901\u0917\u0932\u0940 \u092f\u093e \u0927\u094d\u092f\u093e\u0928 \u0915\u094b \u0924\u0948\u092f\u093e\u0930 \u092a\u0930 \u0924\u091f\u0938\u094d\u0925 \u0930\u0916\u0947\u0902, stop \u0938\u0902\u0915\u0947\u0924 \u0915\u093e \u0905\u0902\u0926\u093e\u091c\u093c\u093e \u0932\u0917\u093e\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u0909\u0938 \u092a\u0930 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0926\u0947\u0902, \u0914\u0930 \u0915\u0920\u093f\u0928\u093e\u0908 \u0915\u094b \u0905\u092a\u0928\u0947-\u0906\u092a \u0922\u0932\u0928\u0947 \u0926\u0947\u0902 \u0924\u093e\u0915\u093f \u0906\u092a \u0915\u093c\u0930\u0940\u092c \u0906\u0927\u0947 stop \u091f\u094d\u0930\u093e\u092f\u0932\u094b\u0902 \u092e\u0947\u0902 \u0938\u092b\u0932 \u0939\u094b \u0930\u0939\u0947 \u0939\u094b\u0902 \u2014 \u0905\u0938\u0932\u0940 \u092e\u0947\u0939\u0928\u0924 \u0920\u0940\u0915 \u092f\u0939\u0940\u0902 \u0939\u094b\u0924\u0940 \u0939\u0948\u0964",duration:"\u091b\u094b\u091f\u0947, \u092c\u093e\u0930-\u092c\u093e\u0930 \u0915\u0947 \u0938\u0924\u094d\u0930 \u092e\u0948\u0930\u093e\u0925\u0928 \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u0939\u0948\u0902: \u0915\u093c\u0930\u0940\u092c 10 \u0938\u0947 15 \u092e\u093f\u0928\u091f, \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u0924\u0940\u0928 \u092f\u093e \u091a\u093e\u0930 \u092c\u093e\u0930, \u0915\u093e\u092b\u093c\u0940 \u0939\u0948\u0902\u0964 \u0928\u093f\u0930\u094b\u0927 \u091c\u0932\u094d\u0926\u0940 \u0925\u0915 \u091c\u093e\u0924\u093e \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u091c\u0948\u0938\u0947 \u0939\u0940 \u0906\u092a\u0915\u093e \u0930\u094b\u0915\u0928\u093e \u0922\u0940\u0932\u093e \u0914\u0930 \u0927\u0940\u092e\u093e \u092a\u0921\u093c\u0928\u0947 \u0932\u0917\u0947, \u0909\u0938 \u0926\u093f\u0928 \u0915\u0947 \u0932\u093f\u090f \u0930\u0941\u0915 \u091c\u093e\u090f\u0901, \u0928 \u0915\u093f \u091c\u093c\u094b\u0930 \u0932\u0917\u093e\u0924\u0947 \u0930\u0939\u0947\u0902\u0964",research:"\u091c\u094b \u092a\u0941\u0916\u093c\u094d\u0924\u093e \u0922\u0902\u0917 \u0938\u0947 \u0926\u093f\u0916\u093e \u0939\u0948 \u0935\u0939 \u0938\u0902\u0915\u0930\u093e \u0939\u0948: \u0932\u094b\u0917 \u0907\u0938 \u091f\u093e\u0938\u094d\u0915 \u0915\u0947 \u092d\u0940\u0924\u0930 \u0930\u094b\u0915\u0928\u0947 \u092e\u0947\u0902 \u092e\u093e\u092a\u0947 \u091c\u093e \u0938\u0915\u0928\u0947 \u0932\u093e\u092f\u0915\u093c \u0924\u0947\u091c\u093c \u0914\u0930 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 stop-signal reaction time \u0928\u093f\u0930\u094b\u0927 \u0915\u093e \u090f\u0915 \u0905\u091a\u094d\u091b\u0940 \u0924\u0930\u0939 \u0938\u0924\u094d\u092f\u093e\u092a\u093f\u0924 \u0938\u0942\u091a\u0915\u093e\u0902\u0915 \u0939\u0948\u0964 \u0935\u094d\u092f\u093e\u092a\u0915 \u092b\u093c\u093e\u092f\u0926\u0947 \u0915\u0939\u0940\u0902 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0915\u092e\u091c\u093c\u094b\u0930 \u0939\u0948\u0902\u0964 \u0907\u0938 \u092c\u093e\u0924 \u0915\u0947 \u0938\u092c\u0942\u0924 \u092e\u093f\u0932\u0947-\u091c\u0941\u0932\u0947 \u0939\u0948\u0902 \u0914\u0930 \u0905\u0915\u094d\u0938\u0930 \u091f\u093f\u0915\u0924\u0947 \u0928\u0939\u0940\u0902 \u0915\u093f \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0947 \u0906\u0924\u094d\u092e-\u0928\u093f\u092f\u0902\u0924\u094d\u0930\u0923 \u092f\u093e \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u0906\u0935\u0947\u0917 \u0924\u0915 \u092a\u0939\u0941\u0901\u091a\u0924\u093e \u0939\u0948; \u0914\u0930 \u091c\u094b \u0932\u093e\u0917\u0942 \u0938\u0902\u0938\u094d\u0915\u0930\u0923 stop \u0938\u0902\u0915\u0947\u0924\u094b\u0902 \u0915\u094b \u092d\u094b\u091c\u0928 \u092f\u093e \u0936\u0930\u093e\u092c \u0915\u0947 \u0938\u0902\u0915\u0947\u0924\u094b\u0902 \u0938\u0947 \u091c\u094b\u0921\u093c\u0924\u0947 \u0939\u0948\u0902, \u0935\u0947 \u0925\u094b\u0921\u093c\u0940 \u0926\u0947\u0930 \u0915\u0947 \u0932\u093f\u090f \u0938\u0947\u0935\u0928 \u0915\u0941\u091b \u0918\u091f\u093e \u0938\u0915\u0924\u0947 \u0939\u0948\u0902, \u092a\u0930 \u0909\u0928\u0915\u0947 \u0905\u0938\u0930 \u092e\u093e\u092e\u0942\u0932\u0940 \u0914\u0930 \u0905\u0915\u094d\u0938\u0930 \u0905\u0932\u094d\u092a\u0915\u093e\u0932\u093f\u0915 \u0930\u0939\u0924\u0947 \u0939\u0948\u0902\u0964 \u092f\u0939 \u0926\u093e\u0935\u0947 \u0915\u093f \u092f\u0939 \u0906\u0924\u094d\u092e-\u0905\u0928\u0941\u0936\u093e\u0938\u0928 \u0915\u094b \u091f\u093f\u0915\u093e\u090a \u0922\u0902\u0917 \u0938\u0947 \u092c\u0922\u093c\u093e\u0924\u093e \u0939\u0948 \u092f\u093e \u0938\u0902\u091c\u094d\u091e\u093e\u0928\u093e\u0924\u094d\u092e\u0915 \u0917\u093f\u0930\u093e\u0935\u091f \u0930\u094b\u0915\u0924\u093e \u0939\u0948, \u0938\u093f\u0926\u094d\u0927 \u0928\u0939\u0940\u0902 \u0939\u0948\u0902, \u0907\u0938\u0932\u093f\u090f \u092c\u0921\u093c\u0947 \u0935\u093e\u0926\u094b\u0902 \u0915\u094b \u0938\u093e\u0935\u0927\u093e\u0928\u0940 \u0938\u0947 \u0932\u0947\u0902\u0964",rec:"\u0907\u0938\u0947 \u0907\u091a\u094d\u091b\u093e\u0936\u0915\u094d\u0924\u093f \u0915\u093e \u0905\u092a\u0917\u094d\u0930\u0947\u0921 \u0928\u0939\u0940\u0902, \u092c\u0932\u094d\u0915\u093f \u0908\u092e\u093e\u0928\u0926\u093e\u0930 \u092c\u094d\u0930\u0947\u0915-\u0905\u092d\u094d\u092f\u093e\u0938 \u0938\u092e\u091d\u0947\u0902: go \u091f\u094d\u0930\u093e\u092f\u0932\u094b\u0902 \u092a\u0930 \u092a\u0942\u0930\u0940 \u0924\u093e\u0915\u093c\u0924 \u0932\u0917\u093e\u090f\u0901 \u0914\u0930 stop \u0938\u0902\u0915\u0947\u0924\u094b\u0902 \u0915\u094b \u0906\u092a\u0915\u094b \u092c\u0947\u0916\u093c\u092c\u0930\u0940 \u092e\u0947\u0902 \u092a\u0915\u0921\u093c\u0928\u0947 \u0926\u0947\u0902\u0964",faq:[["\u0905\u0917\u0930 \u092e\u0948\u0902 \u092c\u0939\u0941\u0924 \u092c\u093e\u0930 \u0930\u0941\u0915\u0928\u0947 \u092e\u0947\u0902 \u0928\u093e\u0915\u093e\u092e \u0930\u0939\u0924\u093e \u0939\u0942\u0901, \u0924\u094b \u0915\u094d\u092f\u093e \u092f\u0939 \u092c\u0941\u0930\u093e \u0939\u0948?","\u0928\u0939\u0940\u0902, \u092f\u0939 \u0924\u094b \u0905\u092a\u0947\u0915\u094d\u0937\u093f\u0924 \u0939\u0940 \u0939\u0948\u0964 \u090f\u0915 \u0905\u091a\u094d\u091b\u093e \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0906\u092a\u0915\u094b \u091c\u093e\u0928-\u092c\u0942\u091d\u0915\u0930 \u0915\u093c\u0930\u0940\u092c 50 \u092a\u094d\u0930\u0924\u093f\u0936\u0924 \u0930\u094b\u0915\u0928\u0947 \u0915\u0940 \u0926\u0930 \u0915\u0947 \u092a\u093e\u0938 \u0930\u0916\u0924\u093e \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0932\u0917\u092d\u0917 \u0906\u0927\u0947 stop \u091f\u094d\u0930\u093e\u092f\u0932\u094b\u0902 \u092e\u0947\u0902 \u0928\u093e\u0915\u093e\u092e \u0930\u0939\u0928\u0947 \u0915\u093e \u092e\u0924\u0932\u092c \u0939\u0948 \u0915\u093f \u092f\u0939 \u0938\u0939\u0940 \u0922\u0902\u0917 \u0938\u0947 \u0938\u092e\u093e\u092f\u094b\u091c\u093f\u0924 \u0939\u0948, \u0928 \u0915\u093f \u0906\u092a \u0915\u0941\u091b \u0917\u093c\u0932\u0924 \u0915\u0930 \u0930\u0939\u0947 \u0939\u0948\u0902\u0964"],["\u0915\u094d\u092f\u093e \u092e\u0941\u091d\u0947 \u091c\u0935\u093e\u092c \u0926\u0947\u0928\u0947 \u0938\u0947 \u092a\u0939\u0932\u0947 \u090f\u0915 \u092a\u0932 \u0930\u0941\u0915\u0928\u093e \u091a\u093e\u0939\u093f\u090f \u0924\u093e\u0915\u093f stop \u0938\u0902\u0915\u0947\u0924 \u092a\u0915\u0921\u093c \u0938\u0915\u0942\u0901?","\u0928\u0939\u0940\u0902, \u0907\u0938\u0938\u0947 \u092a\u0942\u0930\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0939\u0940 \u092c\u0947\u0915\u093e\u0930 \u0939\u094b \u091c\u093e\u0924\u093e \u0939\u0948\u0964 \u091c\u093e\u0928-\u092c\u0942\u091d\u0915\u0930 \u0927\u0940\u092e\u0947 \u0939\u094b\u0915\u0930 \u0906\u092a \u091f\u093e\u0932\u092e\u091f\u094b\u0932 \u0915\u0930\u0915\u0947 '\u091c\u0940\u0924' \u091c\u093e\u0924\u0947 \u0939\u0948\u0902, \u091c\u093f\u0938\u0938\u0947 \u0938\u094d\u0915\u094b\u0930 \u092c\u0947\u092e\u0924\u0932\u092c \u0939\u094b \u091c\u093e\u0924\u093e \u0939\u0948\u0964 go \u0938\u0902\u0915\u0947\u0924\u094b\u0902 \u092a\u0930 \u0924\u0947\u091c\u093c\u0940 \u0938\u0947 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0926\u0947\u0902 \u0914\u0930 \u0924\u092d\u0940 \u092c\u094d\u0930\u0947\u0915 \u0932\u0917\u093e\u090f\u0901 \u091c\u092c stop \u0938\u0902\u0915\u0947\u0924 \u0938\u091a\u092e\u0941\u091a \u0906\u090f\u0964"],["\u0915\u094d\u092f\u093e \u0907\u0938\u0938\u0947 \u092e\u0948\u0902 \u0905\u0938\u0932 \u091c\u093c\u093f\u0902\u0926\u0917\u0940 \u092e\u0947\u0902 \u0915\u092e \u0906\u0935\u0947\u0917\u0940 \u0939\u094b \u091c\u093e\u090a\u0901\u0917\u093e?","\u092f\u0939 \u091f\u093e\u0938\u094d\u0915 \u0915\u0947 \u092d\u0940\u0924\u0930 \u0906\u092a\u0915\u0947 \u0930\u094b\u0915\u0928\u0947 \u0915\u094b \u0924\u094b \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0922\u0902\u0917 \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u0915\u0930\u0947\u0917\u093e, \u092a\u0930 \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0947 \u0906\u0935\u0947\u0917-\u0928\u093f\u092f\u0902\u0924\u094d\u0930\u0923 \u0924\u0915 \u0907\u0938\u0915\u093e \u0905\u0938\u0930 \u0905\u0928\u093f\u0936\u094d\u091a\u093f\u0924 \u0939\u0948 \u0914\u0930 \u0936\u094b\u0927 \u092e\u093f\u0932\u093e-\u091c\u0941\u0932\u093e \u0939\u0948\u0964 \u0907\u0938\u0947 \u092c\u094d\u0930\u0947\u0915-\u0930\u093f\u092b\u093c\u094d\u0932\u0947\u0915\u094d\u0938 \u0915\u0947 \u0932\u093f\u090f \u0932\u0915\u094d\u0937\u093f\u0924 \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u0915\u0940 \u0924\u0930\u0939 \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0915\u0930\u0947\u0902, \u0906\u0935\u0947\u0917 \u0915\u0947 \u092a\u0915\u094d\u0915\u0947 \u0907\u0932\u093e\u091c \u0915\u0940 \u0924\u0930\u0939 \u0928\u0939\u0940\u0902\u0964"]],variants:"\u0907\u0938\u0915\u0947 \u0915\u093c\u0930\u0940\u092c\u0940 \u0930\u093f\u0936\u094d\u0924\u0947\u0926\u093e\u0930\u094b\u0902 \u092e\u0947\u0902 go/no-go \u091f\u093e\u0938\u094d\u0915 \u0939\u0948, \u091c\u093f\u0938\u092e\u0947\u0902 \u0906\u092a \u0909\u0938 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0915\u094b \u0930\u094b\u0915\u0924\u0947 \u0939\u0948\u0902 \u091c\u094b \u0915\u092d\u0940 \u0936\u0941\u0930\u0942 \u0939\u0940 \u0928\u0939\u0940\u0902 \u0939\u0941\u0908 \u0925\u0940, \u0928 \u0915\u093f \u0915\u093f\u0938\u0940 \u091a\u0932\u0924\u0940 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0915\u094b \u0930\u0926\u094d\u0926 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902\u0964 stop \u0938\u0902\u0915\u0947\u0924 \u0916\u093c\u0941\u0926 \u090f\u0915 \u0938\u094d\u0935\u0930, \u0930\u0902\u0917-\u092c\u0926\u0932\u093e\u0935, \u092f\u093e \u090f\u0915 \u0905\u0924\u093f\u0930\u093f\u0915\u094d\u0924 \u091a\u093f\u0939\u094d\u0928 \u0915\u0947 \u092c\u0940\u091a \u092c\u0926\u0932\u0924\u093e \u0930\u0939\u0924\u093e \u0939\u0948, \u0914\u0930 \u0932\u093e\u0917\u0942 \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0905\u0938\u0932 \u091c\u093c\u093f\u0902\u0926\u0917\u0940 \u0915\u0947 \u0906\u0935\u0947\u0917\u094b\u0902 \u0915\u093e \u0905\u0927\u094d\u092f\u092f\u0928 \u0924\u0925\u093e \u0909\u0928\u094d\u0939\u0947\u0902 \u0922\u093e\u0932\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f stop \u0915\u094b \u0932\u0941\u092d\u093e\u0935\u0928\u0947 \u0916\u093e\u0928\u0947 \u092f\u093e \u0936\u0930\u093e\u092c \u091c\u0948\u0938\u0940 \u0916\u093c\u093e\u0938 \u0924\u0938\u094d\u0935\u0940\u0930\u094b\u0902 \u0938\u0947 \u091c\u094b\u0921\u093c \u0926\u0947\u0924\u0947 \u0939\u0948\u0902\u0964"},zh:{about:"\u505c\u6b62\u4fe1\u53f7\uff1a\u6291\u5236\uff0c\u8bad\u7ec3\u7684\u662f\u7ed9\u4e00\u4e2a\u4f60\u5df2\u7ecf\u5f00\u59cb\u7684\u52a8\u4f5c\u8e29\u5239\u8f66\u3002\u4f60\u8981\u5bf9\u4e00\u8fde\u4e32\u6301\u7eed\u51fa\u73b0\u7684\u201cgo\u201d\u7ebf\u7d22\u5c3d\u5feb\u53cd\u5e94\uff08\u6bd4\u5982\u770b\u5230\u7bad\u5934\u5c31\u5411\u5de6\u6216\u5411\u53f3\u70b9\u51fb\uff09\uff0c\u4f46\u5728\u5c11\u6570\u8bd5\u6b21\u91cc\uff0c\u505c\u6b62\u4fe1\u53f7\u4f1a\u5728\u96f6\u70b9\u51e0\u79d2\u540e\u51fa\u73b0\uff0c\u78b0\u5230\u5b83\u4eec\u65f6\uff0c\u4f60\u5fc5\u987b\u4e2d\u6b62\u90a3\u4e2a\u4f60\u5df2\u7ecf\u5728\u542f\u52a8\u7684\u53cd\u5e94\u3002",benefit:"\u5b83\u9488\u5bf9\u53cd\u5e94\u6291\u5236\u2014\u2014\u4e5f\u5c31\u662f\u5728\u52a8\u4f5c\u8fdb\u884c\u5230\u4e00\u534a\u65f6\u628a\u5b83\u53d6\u6d88\u7684\u6267\u884c\u63a7\u5236\u80fd\u529b\u3002\u8fd9\u6b63\u662f\u4f60\u7528\u6765\u538b\u4f4f\u53cd\u5c04\u3001\u5728\u51fa\u9519\u524d\u53ca\u65f6\u6536\u624b\u3001\u6216\u5728\u51b2\u52a8\u4f38\u624b\u53bb\u62ff\u4e1c\u897f\u65f6\u505c\u4e0b\u6765\u7684\u90a3\u5957\u673a\u5236\u3002",history:"\u7528\u4e00\u4e2a\u5ef6\u8fdf\u51fa\u73b0\u7684\u4fe1\u53f7\u53bb\u53d6\u6d88\u4e00\u4e2a\u53cd\u5e94\u65f6\u53cd\u5e94\uff0c\u8fd9\u4e2a\u60f3\u6cd5\u53ef\u4ee5\u8ffd\u6eaf\u5230 1966 \u5e74\u7684 Lappin \u548c Eriksen\u3002\u5230 1984 \u5e74\uff0cLogan \u548c Cowan \u628a\u201c\u8d5b\u9a6c\u6a21\u578b\u201d\u5f62\u5f0f\u5316\uff0c\u5b83\u624d\u6210\u4e3a\u4e00\u79cd\u7cbe\u786e\u7684\u6d4b\u91cf\u5de5\u5177\uff1b\u4ece 1990 \u5e74\u4ee3\u8d77\uff0c\u5b83\u6269\u5c55\u5230\u5173\u4e8e\u591a\u52a8\u75c7\u3001\u6210\u763e\u548c\u51b2\u52a8\u6027\u7684\u4e34\u5e8a\u4e0e\u795e\u7ecf\u79d1\u5b66\u7814\u7a76\u4e2d\uff0c\u540e\u6765\u53c8\u8fdb\u5165\u9762\u5411\u5927\u4f17\u7684\u8111\u529b\u8bad\u7ec3\u5e94\u7528\u3002",creator:"\u5176\u80cc\u540e\u7684\u6838\u5fc3\u60f3\u6cd5\u5e76\u6ca1\u6709\u5355\u4e00\u7684\u53d1\u660e\u8005\u3002\u4e00\u9879\u65e9\u671f\u7684\u89c6\u89c9\u505c\u6b62\u4fe1\u53f7\u5b9e\u9a8c\u7531 Joseph Lappin \u548c Charles Eriksen \u4e8e 1966 \u5e74\u53d1\u8868\uff0c\u800c\u5e26\u6709\u53ef\u6d4b\u91cf\u6291\u5236\u65f6\u95f4\u7684\u73b0\u4ee3\u7248\u4efb\u52a1\uff0c\u7531 Gordon Logan \u548c William Cowan \u4e8e 1984 \u5e74\u51ed\u8bba\u6587\u300aOn the ability to inhibit simple and choice reaction time responses\u300b\u786e\u7acb\u3002",methods:"\u5728\u6bcf\u4e00\u4e2a\u8bd5\u6b21\u4e0a\u90fd\u5168\u529b\u4ee5\u8d74\u5730\u6c42\u5feb\uff0c\u56e0\u4e3a\u6545\u610f\u653e\u6162\u53bb\u7b49\u505c\u6b62\u4fe1\u53f7\u662f\u4f5c\u5f0a\uff0c\u4f1a\u6bc1\u6389\u6d4b\u91cf\u3002\u8ba9\u4f60\u7684\u624b\u6307\u6216\u6ce8\u610f\u529b\u84c4\u52bf\u5f85\u53d1\u4f46\u4fdd\u6301\u4e2d\u7acb\uff0c\u5bf9\u505c\u6b62\u4fe1\u53f7\u8981\u505a\u51fa\u53cd\u5e94\u800c\u4e0d\u662f\u53bb\u9884\u6d4b\u5b83\uff0c\u5e76\u8ba9\u96be\u5ea6\u81ea\u52a8\u8c03\u6574\uff0c\u4f7f\u4f60\u5927\u7ea6\u5728\u4e00\u534a\u7684\u505c\u6b62\u8bd5\u6b21\u4e0a\u6210\u529f\u2014\u2014\u771f\u6b63\u7684\u8bad\u7ec3\u5c31\u53d1\u751f\u5728\u90a3\u91cc\u3002",duration:"\u77ed\u800c\u9891\u7e41\u7684\u8bad\u7ec3\u80dc\u8fc7\u9a6c\u62c9\u677e\uff1a\u5927\u7ea6\u6bcf\u6b21 10 \u5230 15 \u5206\u949f\u3001\u6bcf\u5468\u4e09\u56db\u6b21\uff0c\u5c31\u8db3\u591f\u4e86\u3002\u6291\u5236\u5f88\u5feb\u5c31\u4f1a\u75b2\u52b3\uff0c\u6240\u4ee5\u4e00\u65e6\u4f60\u7684\u201c\u505c\u201d\u53d8\u5f97\u62d6\u6c93\u8fdf\u949d\uff0c\u5c31\u5f53\u5929\u6536\u624b\uff0c\u522b\u786c\u6491\u3002",research:"\u88ab\u624e\u5b9e\u8bc1\u660e\u7684\u7ed3\u8bba\u8303\u56f4\u5f88\u7a84\uff1a\u4eba\u4eec\u5728\u8fd9\u9879\u4efb\u52a1\u5185\u4f1a\u53d8\u5f97\u660e\u663e\u66f4\u5feb\u3001\u66f4\u7a33\u5b9a\u5730\u505c\u4e0b\uff0c\u800c\u505c\u6b62\u4fe1\u53f7\u53cd\u5e94\u65f6\u662f\u4e00\u4e2a\u7ecf\u8fc7\u5145\u5206\u9a8c\u8bc1\u7684\u6291\u5236\u6307\u6807\u3002\u66f4\u5bbd\u6cdb\u7684\u56de\u62a5\u5219\u5f31\u5f97\u591a\u3002\u5173\u4e8e\u8bad\u7ec3\u80fd\u8fc1\u79fb\u5230\u65e5\u5e38\u81ea\u63a7\u6216\u4e00\u822c\u51b2\u52a8\u6027\u7684\u8bc1\u636e\u662f\u6df7\u6742\u7684\uff0c\u800c\u4e14\u5e38\u5e38\u7ecf\u4e0d\u8d77\u68c0\u9a8c\uff1b\u628a\u505c\u6b62\u4fe1\u53f7\u4e0e\u98df\u7269\u6216\u9152\u7cbe\u7ebf\u7d22\u914d\u5bf9\u7684\u5e94\u7528\u7248\u672c\uff0c\u80fd\u5728\u77ed\u671f\u5185\u7565\u5fae\u538b\u4f4e\u6444\u5165\u91cf\uff0c\u4f46\u6548\u679c\u4e0d\u5927\uff0c\u800c\u4e14\u5f80\u5f80\u5f88\u5feb\u6d88\u9000\u3002\u8bf4\u5b83\u80fd\u6301\u4e45\u63d0\u5347\u81ea\u5f8b\u3001\u6216\u80fd\u9884\u9632\u8ba4\u77e5\u8870\u9000\uff0c\u90fd\u6ca1\u6709\u5b9a\u8bba\uff0c\u6240\u4ee5\u5bf9\u90a3\u4e9b\u5b8f\u5927\u7684\u627f\u8bfa\u8981\u4fdd\u6301\u8c28\u614e\u3002",rec:"\u628a\u5b83\u5f53\u4f5c\u8001\u8001\u5b9e\u5b9e\u7684\u5239\u8f66\u7ec3\u4e60\uff0c\u800c\u4e0d\u662f\u610f\u5fd7\u529b\u7684\u5347\u7ea7\uff1a\u5728\u201cgo\u201d\u8bd5\u6b21\u4e0a\u5168\u529b\u4ee5\u8d74\uff0c\u8ba9\u505c\u6b62\u4fe1\u53f7\u6253\u4f60\u4e2a\u63aa\u624b\u4e0d\u53ca\u3002",faq:[["\u6211\u7ecf\u5e38\u505c\u4e0d\u4e0b\u6765\uff0c\u8fd9\u6837\u4e0d\u597d\u5417\uff1f","\u4e0d\uff0c\u8fd9\u662f\u9884\u6599\u4e4b\u4e2d\u7684\u3002\u597d\u7684\u7248\u672c\u4f1a\u6709\u610f\u628a\u4f60\u7ef4\u6301\u5728\u7ea6 50% \u7684\u6210\u529f\u505c\u6b62\u7387\uff0c\u6240\u4ee5\u5927\u7ea6\u4e00\u534a\u7684\u505c\u6b62\u8bd5\u6b21\u5931\u8d25\uff0c\u610f\u5473\u7740\u5b83\u6821\u51c6\u6b63\u786e\uff0c\u800c\u4e0d\u662f\u4f60\u505a\u9519\u4e86\u3002"],["\u6211\u8be5\u4e0d\u8be5\u7b49\u4e00\u62cd\u518d\u53cd\u5e94\uff0c\u597d\u6293\u4f4f\u505c\u6b62\u4fe1\u53f7\uff1f","\u4e0d\u884c\uff0c\u90a3\u6837\u4f1a\u6bc1\u6389\u6574\u4e2a\u7ec3\u4e60\u3002\u6545\u610f\u653e\u6162\u80fd\u8ba9\u4f60\u9760\u62d6\u5ef6\u6765\u201c\u8d62\u201d\uff0c\u8fd9\u4f1a\u8ba9\u6210\u7ee9\u53d8\u5f97\u6beb\u65e0\u610f\u4e49\u3002\u8981\u5bf9\u201cgo\u201d\u7ebf\u7d22\u5feb\u901f\u53cd\u5e94\uff0c\u53ea\u6709\u5f53\u505c\u6b62\u4fe1\u53f7\u771f\u7684\u51fa\u73b0\u65f6\u624d\u8e29\u5239\u8f66\u3002"],["\u8fd9\u4f1a\u8ba9\u6211\u5728\u73b0\u5b9e\u751f\u6d3b\u4e2d\u66f4\u4e0d\u51b2\u52a8\u5417\uff1f","\u5b83\u4f1a\u53ef\u9760\u5730\u63d0\u5347\u4f60\u5728\u4efb\u52a1\u5185\u7684\u505c\u6b62\u80fd\u529b\uff0c\u4f46\u80fd\u5426\u5e26\u5230\u65e5\u5e38\u7684\u51b2\u52a8\u63a7\u5236\u4e0a\u5219\u5e76\u4e0d\u786e\u5b9a\uff0c\u7814\u7a76\u7ed3\u8bba\u4e5f\u662f\u6df7\u6742\u7684\u3002\u628a\u5b83\u5f53\u4f5c\u9488\u5bf9\u5239\u8f66\u53cd\u5c04\u7684\u4e13\u95e8\u8bad\u7ec3\uff0c\u800c\u4e0d\u662f\u6cbb\u51b2\u52a8\u7684\u4fdd\u7968\u3002"]],variants:"\u5b83\u7684\u8fd1\u4eb2\u5305\u62ec go/no-go \u4efb\u52a1\uff0c\u90a3\u91cc\u4f60\u538b\u4f4f\u7684\u662f\u4e00\u4e2a\u6839\u672c\u6ca1\u542f\u52a8\u7684\u53cd\u5e94\uff0c\u800c\u4e0d\u662f\u53d6\u6d88\u4e00\u4e2a\u8fdb\u884c\u4e2d\u7684\u53cd\u5e94\u3002\u505c\u6b62\u4fe1\u53f7\u672c\u8eab\u4e5f\u6709\u53d8\u5316\uff0c\u53ef\u4ee5\u662f\u4e00\u4e2a\u58f0\u97f3\u3001\u4e00\u6b21\u989c\u8272\u53d8\u5316\u6216\u4e00\u4e2a\u989d\u5916\u7b26\u53f7\uff1b\u5e94\u7528\u7248\u672c\u4f1a\u628a\u505c\u6b62\u4fe1\u53f7\u7ed1\u5b9a\u5230\u7279\u5b9a\u56fe\u50cf\u4e0a\uff0c\u6bd4\u5982\u8bf1\u4eba\u7684\u98df\u7269\u6216\u9152\u7cbe\uff0c\u4ee5\u7814\u7a76\u5e76\u5851\u9020\u73b0\u5b9e\u4e2d\u7684\u51b2\u52a8\u3002"}},"story-recall":{ru:{about:"\u0412\u044b \u043e\u0434\u0438\u043d \u0440\u0430\u0437 \u0447\u0438\u0442\u0430\u0435\u0442\u0435 \u0438\u043b\u0438 \u0441\u043b\u0443\u0448\u0430\u0435\u0442\u0435 \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u0439 \u0440\u0430\u0441\u0441\u043a\u0430\u0437, \u0430 \u0437\u0430\u0442\u0435\u043c \u0432\u043e\u0441\u0441\u0442\u0430\u043d\u0430\u0432\u043b\u0438\u0432\u0430\u0435\u0442\u0435 \u0435\u0433\u043e \u043f\u043e \u043f\u0430\u043c\u044f\u0442\u0438, \u0432\u0441\u043f\u043e\u043c\u0438\u043d\u0430\u044f \u043a\u0430\u043a \u043c\u043e\u0436\u043d\u043e \u0431\u043e\u043b\u044c\u0448\u0435 \u043a\u043e\u043d\u043a\u0440\u0435\u0442\u043d\u044b\u0445 \u0434\u0435\u0442\u0430\u043b\u0435\u0439: \u0438\u043c\u0435\u043d\u0430, \u0447\u0438\u0441\u043b\u0430, \u043c\u0435\u0441\u0442\u0430, \u043f\u043e\u0440\u044f\u0434\u043e\u043a \u0441\u043e\u0431\u044b\u0442\u0438\u0439. \u0417\u0430\u0441\u0447\u0438\u0442\u044b\u0432\u0430\u044e\u0442\u0441\u044f \u0438\u043c\u0435\u043d\u043d\u043e \u044d\u043b\u0435\u043c\u0435\u043d\u0442\u044b \u0441\u044e\u0436\u0435\u0442\u0430, \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u0432\u044b \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u0435\u043b\u0438, \u0430 \u043d\u0435 \u043a\u0430\u0447\u0435\u0441\u0442\u0432\u043e \u043f\u0435\u0440\u0435\u0441\u043a\u0430\u0437\u0430, \u2014 \u0432\u0435\u0441\u044c \u043d\u0430\u0432\u044b\u043a \u0432 \u0442\u043e\u043c, \u0447\u0442\u043e\u0431\u044b \u0443\u0445\u0432\u0430\u0442\u0438\u0442\u044c \u0438 \u0443\u0434\u0435\u0440\u0436\u0430\u0442\u044c \u0444\u0430\u043a\u0442\u044b \u043e\u0434\u043d\u043e\u0439 \u0438\u0441\u0442\u043e\u0440\u0438\u0438.",benefit:"\u0422\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442\u0441\u044f \u0441\u043b\u043e\u0432\u0435\u0441\u043d\u0430\u044f \u044d\u043f\u0438\u0437\u043e\u0434\u0438\u0447\u0435\u0441\u043a\u0430\u044f \u043f\u0430\u043c\u044f\u0442\u044c: \u043a\u0430\u043a \u0432\u044b \u043a\u043e\u0434\u0438\u0440\u0443\u0435\u0442\u0435 \u043e\u0441\u043c\u044b\u0441\u043b\u0435\u043d\u043d\u044b\u0439 \u0442\u0435\u043a\u0441\u0442, \u043d\u0435\u043d\u0430\u0434\u043e\u043b\u0433\u043e \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0435\u0442\u0435 \u0435\u0433\u043e \u0438 \u0442\u043e\u0447\u043d\u043e \u0438\u0437\u0432\u043b\u0435\u043a\u0430\u0435\u0442\u0435 \u0434\u0435\u0442\u0430\u043b\u0438. \u041f\u043e\u0441\u043a\u043e\u043b\u044c\u043a\u0443 \u0440\u0430\u0441\u0441\u043a\u0430\u0437 \u0441\u0432\u044f\u0437\u043d\u044b\u0439, \u0430 \u043d\u0435 \u0441\u043b\u0443\u0447\u0430\u0439\u043d\u044b\u0439 \u0441\u043f\u0438\u0441\u043e\u043a, \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u0435 \u043f\u0440\u043e\u043a\u0430\u0447\u0438\u0432\u0430\u0435\u0442 \u0438 \u0443\u043c\u0435\u043d\u0438\u0435 \u0441\u0448\u0438\u0432\u0430\u0442\u044c \u0444\u0430\u043a\u0442\u044b \u0432 \u0446\u0435\u043b\u044c\u043d\u0443\u044e \u0441\u0442\u0440\u0443\u043a\u0442\u0443\u0440\u0443 \u0438 \u0434\u043e\u0441\u0442\u0430\u0432\u0430\u0442\u044c \u0438\u0445 \u043f\u043e \u043f\u043e\u0440\u044f\u0434\u043a\u0443.",history:"\u041f\u0435\u0440\u0435\u0441\u043a\u0430\u0437 \u0443\u0441\u043b\u044b\u0448\u0430\u043d\u043d\u043e\u0433\u043e \u043e\u0442\u0440\u044b\u0432\u043a\u0430 \u2014 \u043e\u0434\u0438\u043d \u0438\u0437 \u0441\u0442\u0430\u0440\u0435\u0439\u0448\u0438\u0445 \u0444\u043e\u0440\u043c\u0430\u0442\u043e\u0432 \u0432 \u043f\u0440\u043e\u0432\u0435\u0440\u043a\u0435 \u043f\u0430\u043c\u044f\u0442\u0438. \u0425\u0430\u0440\u0440\u0438\u0435\u0442 \u0411\u044d\u0431\u043a\u043e\u043a \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u043b\u0430 \u043f\u0440\u0438\u043f\u043e\u043c\u0438\u043d\u0430\u043d\u0438\u0435 \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u0445 \u0440\u0430\u0441\u0441\u043a\u0430\u0437\u043e\u0432 \u0435\u0449\u0451 \u0432 \u0440\u0430\u0431\u043e\u0442\u0435 1930 \u0433\u043e\u0434\u0430 \u043e\u0431 \u0443\u043f\u0430\u0434\u043a\u0435 \u0443\u043c\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0445 \u0444\u0443\u043d\u043a\u0446\u0438\u0439, \u0430 \u0414\u044d\u0432\u0438\u0434 \u0412\u0435\u043a\u0441\u043b\u0435\u0440 \u0432\u0441\u0442\u0440\u043e\u0438\u043b \u0437\u0430\u0434\u0430\u043d\u0438\u0435 \xab\u041b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u0430\u044f \u043f\u0430\u043c\u044f\u0442\u044c\xbb \u0432 \u0441\u0432\u043e\u044e \u0428\u043a\u0430\u043b\u0443 \u043f\u0430\u043c\u044f\u0442\u0438 \u0412\u0435\u043a\u0441\u043b\u0435\u0440\u0430 \u0432 1945 \u0433\u043e\u0434\u0443; \u044d\u0442\u043e\u0442 \u0441\u0443\u0431\u0442\u0435\u0441\u0442 \u0441 \u043d\u0435\u043c\u0435\u0434\u043b\u0435\u043d\u043d\u044b\u043c \u0438 \u043e\u0442\u0441\u0440\u043e\u0447\u0435\u043d\u043d\u044b\u043c \u043f\u0435\u0440\u0435\u0441\u043a\u0430\u0437\u043e\u043c \u0434\u043e\u0448\u0451\u043b \u0434\u043e \u0432\u0441\u0435\u0445 \u043f\u043e\u0441\u043b\u0435\u0434\u0443\u044e\u0449\u0438\u0445 \u0438\u0437\u0434\u0430\u043d\u0438\u0439 \u0438 \u0434\u043e \u0441\u0438\u0445 \u043f\u043e\u0440 \u043e\u0441\u0442\u0430\u0451\u0442\u0441\u044f \u0441\u0442\u0430\u043d\u0434\u0430\u0440\u0442\u043e\u043c \u0432 \u043a\u043b\u0438\u043d\u0438\u043a\u0430\u0445.",creator:"\u0423 \u044d\u0442\u043e\u0433\u043e \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u044f \u043d\u0435\u0442 \u0435\u0434\u0438\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0433\u043e \u0430\u0432\u0442\u043e\u0440\u0430. \u041e\u043d\u043e \u0438\u0434\u0451\u0442 \u0438\u0437 \u043a\u043b\u0438\u043d\u0438\u0447\u0435\u0441\u043a\u043e\u0439 \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u0438 \u043f\u0440\u0438\u043f\u043e\u043c\u0438\u043d\u0430\u043d\u0438\u044f \u0440\u0430\u0441\u0441\u043a\u0430\u0437\u043e\u0432 \u2014 \u0440\u0430\u0431\u043e\u0442\u044b \u0425\u0430\u0440\u0440\u0438\u0435\u0442 \u0411\u044d\u0431\u043a\u043e\u043a 1930 \u0433\u043e\u0434\u0430 \u043e\u0431 \u0443\u043f\u0430\u0434\u043a\u0435 \u0443\u043c\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0445 \u0444\u0443\u043d\u043a\u0446\u0438\u0439 \u0438, \u0447\u0442\u043e \u0432\u0430\u0436\u043d\u0435\u0435 \u0432\u0441\u0435\u0433\u043e, \u0441\u0443\u0431\u0442\u0435\u0441\u0442\u0430 \xab\u041b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u0430\u044f \u043f\u0430\u043c\u044f\u0442\u044c\xbb \u0414\u044d\u0432\u0438\u0434\u0430 \u0412\u0435\u043a\u0441\u043b\u0435\u0440\u0430 \u0432 \u0428\u043a\u0430\u043b\u0435 \u043f\u0430\u043c\u044f\u0442\u0438 \u0412\u0435\u043a\u0441\u043b\u0435\u0440\u0430 (1945). \u0422\u0440\u0435\u043d\u0430\u0436\u0451\u0440 \u2014 \u044d\u0442\u043e \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043e\u0447\u043d\u0430\u044f \u0432\u0435\u0440\u0441\u0438\u044f \u0434\u0430\u0432\u043d\u043e \u0441\u043b\u043e\u0436\u0438\u0432\u0448\u0435\u0433\u043e\u0441\u044f \u0444\u043e\u0440\u043c\u0430\u0442\u0430, \u0430 \u043d\u0435 \u0447\u044c\u0451-\u0442\u043e \u0444\u0438\u0440\u043c\u0435\u043d\u043d\u043e\u0435 \u0438\u0437\u043e\u0431\u0440\u0435\u0442\u0435\u043d\u0438\u0435.",methods:"\u041d\u0430 \u043f\u0435\u0440\u0432\u043e\u043c \u043f\u0440\u043e\u0447\u0442\u0435\u043d\u0438\u0438 \u043b\u043e\u0432\u0438\u0442\u0435 \u0441\u0442\u0435\u0440\u0436\u0435\u043d\u044c \u0438\u0441\u0442\u043e\u0440\u0438\u0438 \u2014 \u043a\u0442\u043e, \u0433\u0434\u0435 \u0438 \u0447\u0442\u043e \u0438\u0437\u043c\u0435\u043d\u0438\u043b\u043e\u0441\u044c, \u2014 \u0430 \u0437\u0430\u0442\u0435\u043c \u043d\u0430\u0432\u0435\u0448\u0438\u0432\u0430\u0439\u0442\u0435 \u043d\u0430 \u044d\u0442\u043e\u0442 \u043a\u0430\u0440\u043a\u0430\u0441 \u043a\u043e\u043d\u043a\u0440\u0435\u0442\u0438\u043a\u0443: \u0447\u0438\u0441\u043b\u0430, \u0438\u043c\u0435\u043d\u0430. \u041f\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043b\u044f\u0439\u0442\u0435 \u0441\u0446\u0435\u043d\u0443 \u0432 \u0434\u0432\u0438\u0436\u0435\u043d\u0438\u0438 \u0438 \u0441\u0432\u044f\u0437\u044b\u0432\u0430\u0439\u0442\u0435 \u0444\u0430\u043a\u0442\u044b \u043f\u0440\u0438\u0447\u0438\u043d\u043e\u0439 \u0438 \u0441\u043b\u0435\u0434\u0441\u0442\u0432\u0438\u0435\u043c, \u0430 \u043d\u0435 \u0437\u0443\u0431\u0440\u0438\u0442\u0435 \u0444\u043e\u0440\u043c\u0443\u043b\u0438\u0440\u043e\u0432\u043a\u0438; \u0441\u0440\u0430\u0437\u0443 \u043f\u043e\u0441\u043b\u0435 \u043f\u0440\u043e\u0447\u0442\u0435\u043d\u0438\u044f \u043f\u0435\u0440\u0435\u0441\u043a\u0430\u0436\u0438\u0442\u0435 \u0432\u0441\u043b\u0443\u0445 \u0438\u043b\u0438 \u043f\u0438\u0441\u044c\u043c\u0435\u043d\u043d\u043e, \u043f\u0440\u0435\u0436\u0434\u0435 \u0447\u0435\u043c \u0441\u0432\u0435\u0440\u0438\u0442\u044c\u0441\u044f, \u2014 \u0438\u043c\u0435\u043d\u043d\u043e \u0441\u0430\u043c\u043e \u0438\u0437\u0432\u043b\u0435\u0447\u0435\u043d\u0438\u0435 \u0438\u0437 \u043f\u0430\u043c\u044f\u0442\u0438 \u0435\u0451 \u0438 \u0443\u043a\u0440\u0435\u043f\u043b\u044f\u0435\u0442.",duration:"\u041b\u0443\u0447\u0448\u0435 \u0440\u0430\u0431\u043e\u0442\u0430\u044e\u0442 \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u0435 \u043f\u043e\u0434\u0445\u043e\u0434\u044b: \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0440\u0430\u0441\u0441\u043a\u0430\u0437\u043e\u0432, \u043f\u0440\u0438\u043c\u0435\u0440\u043d\u043e 10\u201315 \u043c\u0438\u043d\u0443\u0442, \u043f\u0430\u0440\u0443-\u0442\u0440\u043e\u0439\u043a\u0443 \u0440\u0430\u0437 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e. \u0418\u043d\u043e\u0433\u0434\u0430 \u0434\u043e\u0431\u0430\u0432\u043b\u044f\u0439\u0442\u0435 \u043e\u0442\u0441\u0440\u043e\u0447\u0435\u043d\u043d\u044b\u0439 \u043f\u0435\u0440\u0435\u0441\u043a\u0430\u0437 \u0447\u0435\u0440\u0435\u0437 20\u201330 \u043c\u0438\u043d\u0443\u0442 \u2014 \u043e\u0442\u043b\u043e\u0436\u0435\u043d\u043d\u043e\u0435 \u043f\u0440\u0438\u043f\u043e\u043c\u0438\u043d\u0430\u043d\u0438\u0435 \u0441\u043b\u043e\u0436\u043d\u0435\u0435 \u0438 \u043f\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u043d\u0435\u0435, \u0435\u0433\u043e \u0441\u0442\u043e\u0438\u0442 \u043e\u0442\u0440\u0430\u0431\u0430\u0442\u044b\u0432\u0430\u0442\u044c \u043e\u0441\u043e\u0437\u043d\u0430\u043d\u043d\u043e.",research:"\u041d\u0430\u0434\u0451\u0436\u043d\u043e \u0434\u043e\u043a\u0430\u0437\u0430\u043d\u043e \u043d\u0435\u043c\u043d\u043e\u0433\u043e\u0435: \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u044f \u043f\u0435\u0440\u0435\u0441\u043a\u0430\u0437 \u0440\u0430\u0441\u0441\u043a\u0430\u0437\u043e\u0432, \u0432\u044b \u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u0435\u0441\u044c \u043b\u0443\u0447\u0448\u0435 \u0438\u043c\u0435\u043d\u043d\u043e \u0432 \u043f\u0435\u0440\u0435\u0441\u043a\u0430\u0437\u0435 \u0440\u0430\u0441\u0441\u043a\u0430\u0437\u043e\u0432, \u0430 \u0441\u0442\u0440\u0443\u043a\u0442\u0443\u0440\u043d\u043e\u0435 \u043e\u0431\u0443\u0447\u0435\u043d\u0438\u0435 \u043f\u0440\u0438\u0451\u043c\u0430\u043c \u043f\u0430\u043c\u044f\u0442\u0438 \u0441\u0442\u0430\u0431\u0438\u043b\u044c\u043d\u043e \u0443\u043b\u0443\u0447\u0448\u0430\u0435\u0442 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442\u044b \u043d\u0430 \u0441\u0430\u043c\u043e\u0439 \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u043c\u043e\u0439 \u0438 \u0431\u043b\u0438\u0437\u043a\u0438\u0445 \u043a \u043d\u0435\u0439 \u0437\u0430\u0434\u0430\u0447\u0430\u0445 (\u0431\u043b\u0438\u0436\u043d\u0438\u0439 \u043f\u0435\u0440\u0435\u043d\u043e\u0441). \u0428\u0438\u0440\u043e\u043a\u0438\u0435 \u0437\u0430\u044f\u0432\u043b\u0435\u043d\u0438\u044f \u043a\u0443\u0434\u0430 \u0441\u043b\u0430\u0431\u0435\u0435 \u2014 \u0447\u0442\u043e \u044d\u0442\u043e \u043f\u043e\u0434\u043d\u0438\u043c\u0430\u0435\u0442 \u043e\u0431\u0449\u0438\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442, \u043e\u0431\u043e\u0441\u0442\u0440\u044f\u0435\u0442 \u043d\u0435\u0441\u0432\u044f\u0437\u0430\u043d\u043d\u0443\u044e \u0431\u044b\u0442\u043e\u0432\u0443\u044e \u043f\u0430\u043c\u044f\u0442\u044c \u0438\u043b\u0438 \u043f\u0440\u0435\u0434\u043e\u0442\u0432\u0440\u0430\u0449\u0430\u0435\u0442 \u0432\u043e\u0437\u0440\u0430\u0441\u0442\u043d\u043e\u0439 \u0441\u043f\u0430\u0434, \u043f\u043e \u0431\u043e\u043b\u044c\u0448\u0435\u0439 \u0447\u0430\u0441\u0442\u0438 \u043d\u0435 \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043d\u043e, \u0438 \u043a\u0440\u0443\u043f\u043d\u044b\u0435 \u043e\u0431\u0437\u043e\u0440\u044b \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043e\u043a \u043c\u043e\u0437\u0433\u0430 \u0440\u0430\u0437 \u0437\u0430 \u0440\u0430\u0437\u043e\u043c \u043d\u0430\u0445\u043e\u0434\u044f\u0442, \u0447\u0442\u043e \u043f\u0440\u0438\u0440\u043e\u0441\u0442 \u0440\u0435\u0434\u043a\u043e \u0432\u044b\u0445\u043e\u0434\u0438\u0442 \u0434\u0430\u043b\u0435\u043a\u043e \u0437\u0430 \u043f\u0440\u0435\u0434\u0435\u043b\u044b \u043d\u0430\u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u043e\u0433\u043e \u043d\u0430\u0432\u044b\u043a\u0430. \u041e\u0442\u043d\u043e\u0441\u0438\u0442\u0435\u0441\u044c \u043a \u044d\u0442\u043e\u043c\u0443 \u043a\u0430\u043a \u043a \u0447\u0435\u0441\u0442\u043d\u043e\u0439 \u0437\u0430\u0440\u044f\u0434\u043a\u0435 \u0434\u043b\u044f \u0441\u043b\u043e\u0432\u0435\u0441\u043d\u043e\u0439 \u043f\u0430\u043c\u044f\u0442\u0438, \u0430 \u043d\u0435 \u043a\u0430\u043a \u043a \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0443 \u043e\u0442 \u0437\u0430\u0431\u044b\u0432\u0447\u0438\u0432\u043e\u0441\u0442\u0438.",rec:"\u041f\u043e\u0441\u043b\u0435 \u043f\u0435\u0440\u0432\u043e\u0433\u043e \u043f\u0440\u043e\u0447\u0442\u0435\u043d\u0438\u044f \u043f\u0435\u0440\u0435\u0441\u043a\u0430\u0436\u0438\u0442\u0435 \u0438\u0441\u0442\u043e\u0440\u0438\u044e \u0441\u0432\u043e\u0438\u043c\u0438 \u0441\u043b\u043e\u0432\u0430\u043c\u0438, \u043f\u0440\u0435\u0436\u0434\u0435 \u0447\u0435\u043c \u0441\u0432\u0435\u0440\u0438\u0442\u044c\u0441\u044f \u0441 \u0442\u0435\u043a\u0441\u0442\u043e\u043c, \u2014 \u0441\u0430\u043c\u043e\u043f\u0440\u043e\u0432\u0435\u0440\u043a\u0430 \u0437\u0430\u043a\u0440\u0435\u043f\u043b\u044f\u0435\u0442 \u043a\u0443\u0434\u0430 \u0431\u043e\u043b\u044c\u0448\u0435, \u0447\u0435\u043c \u043f\u043e\u0432\u0442\u043e\u0440\u043d\u043e\u0435 \u043f\u0435\u0440\u0435\u0447\u0438\u0442\u044b\u0432\u0430\u043d\u0438\u0435.",faq:[["\u042d\u0442\u043e \u0442\u043e\u0442 \u0436\u0435 \u0442\u0435\u0441\u0442 \xab\u041b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u0430\u044f \u043f\u0430\u043c\u044f\u0442\u044c\xbb, \u0447\u0442\u043e \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u044e\u0442 \u0432\u0440\u0430\u0447\u0438?","\u0424\u043e\u0440\u043c\u0430\u0442 \u0442\u043e\u0442 \u0436\u0435 \u2014 \u0432\u0441\u043f\u043e\u043c\u043d\u0438\u0442\u044c \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u0439 \u0440\u0430\u0441\u0441\u043a\u0430\u0437 \u0441\u0440\u0430\u0437\u0443 \u0438 \u043f\u043e\u0441\u043b\u0435 \u043f\u0430\u0443\u0437\u044b, \u2014 \u043d\u043e \u044d\u0442\u043e \u043f\u043e\u0432\u0441\u0435\u0434\u043d\u0435\u0432\u043d\u0430\u044f \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0430, \u0430 \u043d\u0435 \u043a\u043b\u0438\u043d\u0438\u0447\u0435\u0441\u043a\u0430\u044f \u0434\u0438\u0430\u0433\u043d\u043e\u0441\u0442\u0438\u043a\u0430. \u0422\u0435\u0441\u0442\u043e\u0432\u044b\u0435 \u0432\u0435\u0440\u0441\u0438\u0438 \u0441\u0442\u0430\u043d\u0434\u0430\u0440\u0442\u0438\u0437\u0438\u0440\u043e\u0432\u0430\u043d\u044b \u0438 \u043e\u0446\u0435\u043d\u0438\u0432\u0430\u044e\u0442\u0441\u044f \u0441\u043f\u0435\u0446\u0438\u0430\u043b\u0438\u0441\u0442\u0430\u043c\u0438; \u0442\u0440\u0435\u043d\u0430\u0436\u0451\u0440 \u043f\u0440\u043e\u0441\u0442\u043e \u0434\u0430\u0451\u0442 \u0443\u043f\u0440\u0430\u0436\u043d\u044f\u0442\u044c \u0442\u043e\u0442 \u0436\u0435 \u043d\u0430\u0432\u044b\u043a."],["\u0423\u043b\u0443\u0447\u0448\u0438\u0442 \u043b\u0438 \u044d\u0442\u043e \u043c\u043e\u044e \u043f\u0430\u043c\u044f\u0442\u044c \u0432 \u0446\u0435\u043b\u043e\u043c?","\u041e\u043d \u043d\u0430\u0434\u0451\u0436\u043d\u043e \u043d\u0430\u0443\u0447\u0438\u0442 \u0432\u0430\u0441 \u043b\u0443\u0447\u0448\u0435 \u0437\u0430\u043f\u043e\u043c\u0438\u043d\u0430\u0442\u044c \u0440\u0430\u0441\u0441\u043a\u0430\u0437\u044b \u0438 \u043f\u043e\u0445\u043e\u0436\u0438\u0439 \u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b. \u0428\u0438\u0440\u043e\u043a\u043e\u0433\u043e \u043f\u0440\u0438\u0440\u043e\u0441\u0442\u0430 \u043d\u0435\u0441\u0432\u044f\u0437\u0430\u043d\u043d\u043e\u0439, \u0431\u044b\u0442\u043e\u0432\u043e\u0439 \u043f\u0430\u043c\u044f\u0442\u0438 \u0434\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432\u0430 \u043d\u0435 \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u044e\u0442, \u0442\u0430\u043a \u0447\u0442\u043e \u0436\u0434\u0438\u0442\u0435 \u0443\u043b\u0443\u0447\u0448\u0435\u043d\u0438\u0439 \u0431\u043b\u0438\u0437\u043a\u043e \u043a \u0442\u043e\u043c\u0443, \u0447\u0442\u043e \u0432\u044b \u0440\u0435\u0430\u043b\u044c\u043d\u043e \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442\u0435."],["\u041d\u0443\u0436\u043d\u043e \u043b\u0438 \u0437\u0430\u043f\u043e\u043c\u0438\u043d\u0430\u0442\u044c \u0442\u043e\u0447\u043d\u044b\u0435 \u0441\u043b\u043e\u0432\u0430?","\u041d\u0435\u0442. \u0426\u0435\u043b\u0438\u0442\u0435\u0441\u044c \u0432 \u0441\u043c\u044b\u0441\u043b \u0438 \u043a\u043e\u043d\u043a\u0440\u0435\u0442\u043d\u044b\u0435 \u0434\u0435\u0442\u0430\u043b\u0438 \u2014 \u0447\u0442\u043e \u043f\u0440\u043e\u0438\u0437\u043e\u0448\u043b\u043e, \u0441 \u043a\u0435\u043c, \u0438\u043c\u0435\u043d\u0430 \u0438 \u0447\u0438\u0441\u043b\u0430. \u041f\u043e\u0434\u0441\u0447\u0451\u0442 \u043f\u043e \u0434\u0435\u0442\u0430\u043b\u044f\u043c \u0432\u043e\u0437\u043d\u0430\u0433\u0440\u0430\u0436\u0434\u0430\u0435\u0442 \u0442\u043e\u0447\u043d\u043e\u0435 \u0441\u043e\u0434\u0435\u0440\u0436\u0430\u043d\u0438\u0435, \u0430 \u043f\u0440\u0438\u043f\u043e\u043c\u0438\u043d\u0430\u043d\u0438\u0435 \u043f\u043e \u0441\u043c\u044b\u0441\u043b\u0443 \u0434\u0435\u0440\u0436\u0438\u0442\u0441\u044f \u043a\u0443\u0434\u0430 \u043b\u0443\u0447\u0448\u0435, \u0447\u0435\u043c \u0434\u043e\u0441\u043b\u043e\u0432\u043d\u0430\u044f \u0437\u0443\u0431\u0440\u0451\u0436\u043a\u0430."]],variants:"\u041c\u0435\u043d\u044f\u0439\u0442\u0435 \u043d\u0430\u0433\u0440\u0443\u0437\u043a\u0443 \u0434\u043b\u0438\u043d\u043e\u0439 \u0440\u0430\u0441\u0441\u043a\u0430\u0437\u0430 \u0438 \u043f\u043b\u043e\u0442\u043d\u043e\u0441\u0442\u044c\u044e \u0438\u043c\u0451\u043d, \u0447\u0438\u0441\u0435\u043b \u0438 \u0434\u0430\u0442. \u0427\u0435\u0440\u0435\u0434\u0443\u0439\u0442\u0435 \u0447\u0442\u0435\u043d\u0438\u0435 \u0438 \u0441\u043b\u0443\u0448\u0430\u043d\u0438\u0435, \u043d\u0435\u043c\u0435\u0434\u043b\u0435\u043d\u043d\u043e\u0435 \u0438 \u043e\u0442\u0441\u0440\u043e\u0447\u0435\u043d\u043d\u043e\u0435 (\u0447\u0435\u0440\u0435\u0437 20\u201330 \u043c\u0438\u043d\u0443\u0442) \u043f\u0440\u0438\u043f\u043e\u043c\u0438\u043d\u0430\u043d\u0438\u0435, \u0441\u0432\u043e\u0431\u043e\u0434\u043d\u044b\u0439 \u043f\u0435\u0440\u0435\u0441\u043a\u0430\u0437 \u0438 \u043e\u0442\u0432\u0435\u0442\u044b \u043d\u0430 \u043a\u043e\u043d\u043a\u0440\u0435\u0442\u043d\u044b\u0435 \u0432\u043e\u043f\u0440\u043e\u0441\u044b \u043f\u043e \u0442\u0435\u043a\u0441\u0442\u0443; \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u0435\u0434\u0435\u043d\u0438\u0435 \u0441\u043e\u0431\u044b\u0442\u0438\u0439 \u0441\u0442\u0440\u043e\u0433\u043e \u043f\u043e \u043f\u043e\u0440\u044f\u0434\u043a\u0443 \u2014 \u0435\u0449\u0451 \u043e\u0434\u0438\u043d, \u0431\u043e\u043b\u0435\u0435 \u0442\u0440\u0443\u0434\u043d\u044b\u0439 \u0440\u0435\u0436\u0438\u043c."},en:{about:"You read or listen to a short story once, then reconstruct it from memory, recalling as many concrete details as you can \u2014 names, numbers, places, the order of events. Scoring counts the specific story elements you got back, not how good the writing is, so the whole skill is in capturing and holding the facts of a single narrative.",benefit:"It trains verbal episodic memory: encoding meaningful prose, holding it briefly, and retrieving the details accurately. Because a story is connected rather than a random list, it also exercises the way you bind facts into a coherent structure and recover them in sequence.",history:"Recalling a read-aloud passage is one of the oldest formats in memory testing. Harriet Babcock used short story recall in her 1930 work on mental deterioration, and David Wechsler built a 'Logical Memory' story-recall task into the Wechsler Memory Scale in 1945; that subtest, with immediate and delayed retelling, survives through every later edition and is still standard in clinics today.",creator:"There is no single inventor of this game. It descends from the clinical story-recall tradition \u2014 Harriet Babcock's 1930 mental-deterioration work and, most influentially, David Wechsler's Logical Memory subtest of the Wechsler Memory Scale (1945). The trainer is a practice version of that long-established format, not a branded invention.",methods:"On the first pass, listen for the story's spine \u2014 who, where, and what changed \u2014 then hang the specific details (numbers, names) onto that frame. Picture the scene as it unfolds and link facts into cause and effect rather than memorising words; right after, retell it out loud or in writing before checking, since the act of retrieving is what strengthens the memory.",duration:"Short sessions work best: a handful of stories, roughly 10 to 15 minutes, a few times a week. Add a delayed retelling after 20 to 30 minutes now and then \u2014 delayed recall is the harder, more informative version and worth practising deliberately.",research:"What is solidly shown is narrow: practise story recall and you get better at story recall, and structured memory-strategy training reliably improves performance on the trained and closely similar tasks (near transfer). Broad claims are much weaker \u2014 that it lifts general intelligence, sharpens unrelated everyday memory, or prevents age-related decline is largely unproven, and large reviews of brain training keep finding that gains rarely spread far beyond the practised skill. Treat it as honest exercise for verbal memory, not a cure for forgetfulness.",rec:"After the first read, retell the story in your own words before you check it \u2014 self-testing locks in far more than re-reading does.",faq:[["Is this the same as the Logical Memory test doctors use?","It uses the same format \u2014 recall a short story right away and after a delay \u2014 but as everyday practice, not a clinical assessment. The test versions are standardised and scored by professionals; a trainer just lets you exercise the same skill."],["Will it improve my memory in general?","It will reliably make you better at remembering stories and similar material. A broad boost to unrelated, everyday memory is not well supported by evidence, so expect gains close to what you actually practise."],["Should I memorise the exact words?","No. Aim for the meaning and the concrete details \u2014 what happened, to whom, the names and numbers. Detail-by-detail scoring rewards accurate content, and meaning-based recall holds up far better than word-for-word memorising."]],variants:"Vary the load by story length and by the density of names, numbers and dates. Switch between reading and listening, between immediate and delayed (20-30 minute) recall, and between free retelling and answering specific questions about the passage; recalling events strictly in order is a harder mode again."},es:{about:"Lees o escuchas un relato breve una sola vez y luego lo reconstruyes de memoria, recordando tantos detalles concretos como puedas: nombres, n\xfameros, lugares, el orden de los hechos. La puntuaci\xf3n cuenta los elementos espec\xedficos del relato que has recuperado, no lo bien escrito que est\xe9, as\xed que toda la habilidad est\xe1 en captar y retener los hechos de una \xfanica narraci\xf3n.",benefit:"Entrena la memoria epis\xf3dica verbal: codificar prosa con sentido, retenerla brevemente y recuperar los detalles con exactitud. Como un relato est\xe1 conectado en lugar de ser una lista aleatoria, tambi\xe9n ejercita la forma en que enlazas los hechos en una estructura coherente y los recuperas en secuencia.",history:"Recordar un pasaje le\xeddo en voz alta es uno de los formatos m\xe1s antiguos de la evaluaci\xf3n de la memoria. Harriet Babcock emple\xf3 el recuerdo de relatos breves en su trabajo de 1930 sobre el deterioro mental, y David Wechsler incorpor\xf3 una tarea de recuerdo de relatos, la 'Memoria L\xf3gica', a la Escala de Memoria de Wechsler en 1945; ese subtest, con recuento inmediato y demorado, sobrevive a trav\xe9s de todas las ediciones posteriores y sigue siendo est\xe1ndar en las cl\xednicas de hoy.",creator:"Este juego no tiene un \xfanico inventor. Desciende de la tradici\xf3n cl\xednica del recuerdo de relatos: el trabajo de Harriet Babcock de 1930 sobre el deterioro mental y, de forma m\xe1s influyente, el subtest de Memoria L\xf3gica de la Escala de Memoria de Wechsler, de David Wechsler (1945). El entrenador es una versi\xf3n de pr\xe1ctica de ese formato bien establecido, no una invenci\xf3n de marca.",methods:"En la primera lectura, atiende a la columna vertebral del relato \u2014qui\xe9n, d\xf3nde y qu\xe9 cambi\xf3\u2014 y luego cuelga los detalles concretos (n\xfameros, nombres) de ese armaz\xf3n. Imagina la escena seg\xfan se desarrolla y enlaza los hechos en relaciones de causa y efecto en vez de memorizar palabras; justo despu\xe9s, vuelve a contarlo en voz alta o por escrito antes de comprobarlo, ya que el acto de recuperar es lo que refuerza la memoria.",duration:"Lo mejor son las sesiones cortas: un pu\xf1ado de relatos, unos 10 a 15 minutos, algunas veces por semana. A\xf1ade de vez en cuando un recuento demorado tras 20 a 30 minutos; el recuerdo demorado es la versi\xf3n m\xe1s dif\xedcil e informativa, y vale la pena practicarlo de forma deliberada.",research:"Lo s\xf3lidamente demostrado es estrecho: practica el recuerdo de relatos y mejorar\xe1s en el recuerdo de relatos, y el entrenamiento estructurado en estrategias de memoria mejora de forma fiable el rendimiento en las tareas entrenadas y en otras muy parecidas (transferencia cercana). Las afirmaciones amplias son mucho m\xe1s d\xe9biles: que eleve la inteligencia general, afine la memoria cotidiana no relacionada o prevenga el deterioro asociado a la edad est\xe1 en gran medida sin demostrar, y las grandes revisiones del entrenamiento cerebral siguen hallando que las mejoras rara vez se extienden mucho m\xe1s all\xe1 de la habilidad practicada. T\xf3malo como ejercicio honesto para la memoria verbal, no como cura para los olvidos.",rec:"Tras la primera lectura, vuelve a contar el relato con tus propias palabras antes de comprobarlo; autoevaluarte fija mucho m\xe1s que releer.",faq:[["\xbfEs esto lo mismo que la prueba de Memoria L\xf3gica que usan los m\xe9dicos?","Usa el mismo formato \u2014recordar un relato breve enseguida y tras una demora\u2014, pero como pr\xe1ctica cotidiana, no como evaluaci\xf3n cl\xednica. Las versiones de prueba est\xe1n estandarizadas y las punt\xfaan profesionales; un entrenador solo te deja ejercitar la misma habilidad."],["\xbfMejorar\xe1 mi memoria en general?","Te har\xe1 de forma fiable mejor recordando relatos y material parecido. Un impulso amplio a la memoria cotidiana no relacionada no est\xe1 bien respaldado por la evidencia, as\xed que espera mejoras cercanas a lo que de verdad practicas."],["\xbfDebo memorizar las palabras exactas?","No. Apunta al significado y a los detalles concretos: qu\xe9 pas\xf3, a qui\xe9n, los nombres y los n\xfameros. La puntuaci\xf3n detalle a detalle premia el contenido exacto, y el recuerdo basado en el significado aguanta mucho mejor que memorizar palabra por palabra."]],variants:"Var\xeda la carga seg\xfan la longitud del relato y la densidad de nombres, n\xfameros y fechas. Alterna entre leer y escuchar, entre el recuerdo inmediato y el demorado (20-30 minutos), y entre el recuento libre y responder preguntas concretas sobre el pasaje; recordar los hechos estrictamente en orden es un modo a\xfan m\xe1s dif\xedcil."},de:{about:"Du liest oder h\xf6rst eine kurze Geschichte einmal und rekonstruierst sie dann aus dem Ged\xe4chtnis, indem du so viele konkrete Einzelheiten wie m\xf6glich abrufst \u2013 Namen, Zahlen, Orte, die Reihenfolge der Ereignisse. Bewertet werden die spezifischen Elemente der Geschichte, die du zur\xfcckbekommen hast, nicht wie gut der Text geschrieben ist, sodass die ganze Fertigkeit darin liegt, die Fakten einer einzelnen Erz\xe4hlung zu erfassen und festzuhalten.",benefit:"Trainiert wird das verbale episodische Ged\xe4chtnis: bedeutungsvolle Prosa enkodieren, sie kurz festhalten und die Einzelheiten genau abrufen. Weil eine Geschichte zusammenh\xe4ngend ist und keine zuf\xe4llige Liste, \xfcbst du auch, wie du Fakten zu einer koh\xe4renten Struktur verbindest und sie in der richtigen Abfolge wieder hervorholst.",history:"Das Wiedergeben einer vorgelesenen Passage ist eines der \xe4ltesten Formate der Ged\xe4chtnispr\xfcfung. Harriet Babcock nutzte das Nacherz\xe4hlen kurzer Geschichten 1930 in ihrer Arbeit zum geistigen Abbau, und David Wechsler baute 1945 eine Geschichten-Wiedergabeaufgabe namens \u201eLogisches Ged\xe4chtnis\u201c in die Wechsler Memory Scale ein; dieser Untertest mit unmittelbarem und verz\xf6gertem Nacherz\xe4hlen \xfcberdauert jede sp\xe4tere Auflage und ist in Kliniken bis heute Standard.",creator:"Es gibt keinen einzelnen Erfinder dieses Spiels. Es stammt aus der klinischen Tradition der Geschichten-Wiedergabe \u2013 Harriet Babcocks Arbeit zum geistigen Abbau von 1930 und, am einflussreichsten, David Wechslers Untertest \u201eLogisches Ged\xe4chtnis\u201c der Wechsler Memory Scale (1945). Der Trainer ist eine \xdcbungsversion dieses lange etablierten Formats, keine markenrechtlich gesch\xfctzte Erfindung.",methods:"H\xf6re beim ersten Durchgang auf das R\xfcckgrat der Geschichte \u2013 wer, wo und was sich \xe4nderte \u2013 und h\xe4ng dann die spezifischen Einzelheiten (Zahlen, Namen) an dieses Ger\xfcst. Stell dir die Szene vor, wie sie sich entfaltet, und verkn\xfcpfe Fakten zu Ursache und Wirkung, statt W\xf6rter auswendig zu lernen; erz\xe4hle sie unmittelbar danach laut oder schriftlich nach, bevor du nachschaust, denn der Akt des Abrufens ist es, der das Ged\xe4chtnis st\xe4rkt.",duration:"Kurze Sitzungen funktionieren am besten: eine Handvoll Geschichten, etwa 10 bis 15 Minuten, ein paar Mal pro Woche. F\xfcge hin und wieder ein verz\xf6gertes Nacherz\xe4hlen nach 20 bis 30 Minuten hinzu \u2013 das verz\xf6gerte Abrufen ist die schwerere, aufschlussreichere Version und es wert, gezielt ge\xfcbt zu werden.",research:"Solide gezeigt ist nur Enges: \xdcbst du das Wiedergeben von Geschichten, wirst du besser im Wiedergeben von Geschichten, und ein strukturiertes Ged\xe4chtnisstrategie-Training verbessert zuverl\xe4ssig die Leistung in den trainierten und eng verwandten Aufgaben (Nah-Transfer). Breite Behauptungen sind viel schw\xe4cher \u2013 dass es die allgemeine Intelligenz hebt, das unverwandte Alltagsged\xe4chtnis sch\xe4rft oder altersbedingten Abbau verhindert, ist weitgehend unbewiesen, und gro\xdfe \xdcbersichtsarbeiten zum Gehirntraining finden immer wieder, dass sich Zuw\xe4chse selten weit \xfcber die ge\xfcbte Fertigkeit hinaus ausbreiten. Behandle es als ehrliche \xdcbung f\xfcr das verbale Ged\xe4chtnis, nicht als Heilmittel gegen Vergesslichkeit.",rec:"Erz\xe4hle die Geschichte nach dem ersten Lesen mit eigenen Worten nach, bevor du nachschaust \u2013 sich selbst zu testen verankert weit mehr als erneutes Lesen.",faq:[["Ist das dasselbe wie der Test \u201eLogisches Ged\xe4chtnis\u201c, den \xc4rzte verwenden?","Es nutzt dasselbe Format \u2013 eine kurze Geschichte sofort und nach einer Verz\xf6gerung wiedergeben \u2013, aber als allt\xe4gliche \xdcbung, nicht als klinische Diagnostik. Die Testversionen sind standardisiert und werden von Fachleuten ausgewertet; ein Trainer l\xe4sst dich nur dieselbe Fertigkeit \xfcben."],["Verbessert es mein Ged\xe4chtnis im Allgemeinen?","Es macht dich zuverl\xe4ssig besser darin, Geschichten und \xe4hnliches Material zu behalten. Ein breiter Schub f\xfcr das unverwandte Alltagsged\xe4chtnis ist durch die Belege nicht gut gest\xfctzt \u2013 erwarte also Zuw\xe4chse nahe an dem, was du tats\xe4chlich \xfcbst."],["Soll ich die genauen W\xf6rter auswendig lernen?","Nein. Ziele auf den Sinn und die konkreten Einzelheiten \u2013 was geschah, wem, die Namen und Zahlen. Die Bewertung Einzelheit f\xfcr Einzelheit belohnt genauen Inhalt, und ein sinnbasierter Abruf h\xe4lt weit besser als wortw\xf6rtliches Auswendiglernen."]],variants:"Variiere die Last \xfcber die L\xe4nge der Geschichte und \xfcber die Dichte an Namen, Zahlen und Daten. Wechsle zwischen Lesen und H\xf6ren, zwischen unmittelbarem und verz\xf6gertem (20\u201330 Minuten) Abruf und zwischen freiem Nacherz\xe4hlen und dem Beantworten gezielter Fragen zur Passage; Ereignisse streng in der richtigen Reihenfolge abzurufen ist noch einmal ein schwererer Modus."},pt:{about:"Voc\xea l\xea ou ouve uma hist\xf3ria curta uma vez e depois a reconstr\xf3i de mem\xf3ria, recordando o m\xe1ximo de detalhes concretos que conseguir \u2014 nomes, n\xfameros, lugares, a ordem dos acontecimentos. A pontua\xe7\xe3o conta os elementos espec\xedficos da hist\xf3ria que voc\xea recuperou, n\xe3o a qualidade da escrita, por isso toda a habilidade est\xe1 em captar e reter os factos de uma \xfanica narrativa.",benefit:"Treina a mem\xf3ria epis\xf3dica verbal: codificar uma prosa com sentido, ret\xea-la brevemente e recuperar os detalhes com precis\xe3o. Como uma hist\xf3ria \xe9 encadeada, e n\xe3o uma lista aleat\xf3ria, tamb\xe9m exercita a forma como voc\xea liga os factos numa estrutura coerente e os recupera em sequ\xeancia.",history:"Recordar um trecho lido em voz alta \xe9 um dos formatos mais antigos dos testes de mem\xf3ria. Harriet Babcock usou o recordar de hist\xf3rias curtas no seu trabalho de 1930 sobre a deteriora\xe7\xe3o mental, e David Wechsler incorporou uma tarefa de recordar de hist\xf3rias chamada 'Mem\xf3ria L\xf3gica' na Wechsler Memory Scale em 1945; esse subteste, com recontagem imediata e diferida, sobrevive em todas as edi\xe7\xf5es posteriores e ainda \xe9 padr\xe3o nas cl\xednicas de hoje.",creator:"N\xe3o h\xe1 um inventor \xfanico deste jogo. Ele descende da tradi\xe7\xe3o cl\xednica do recordar de hist\xf3rias \u2014 do trabalho de Harriet Babcock sobre deteriora\xe7\xe3o mental, de 1930, e, de forma mais influente, do subteste de Mem\xf3ria L\xf3gica da Wechsler Memory Scale de David Wechsler (1945). O treinador \xe9 uma vers\xe3o de pr\xe1tica desse formato h\xe1 muito consagrado, n\xe3o uma inven\xe7\xe3o de marca.",methods:"Na primeira passagem, escute pela espinha dorsal da hist\xf3ria \u2014 quem, onde e o que mudou \u2014 e depois pendure os detalhes espec\xedficos (n\xfameros, nomes) nessa estrutura. Visualize a cena \xe0 medida que ela se desenrola e ligue os factos em causa e efeito, em vez de decorar palavras; logo a seguir, reconte em voz alta ou por escrito antes de conferir, pois \xe9 o ato de recuperar que fortalece a mem\xf3ria.",duration:"As sess\xf5es curtas funcionam melhor: um punhado de hist\xf3rias, cerca de 10 a 15 minutos, algumas vezes por semana. De vez em quando, acrescente uma recontagem diferida ap\xf3s 20 a 30 minutos \u2014 a recorda\xe7\xe3o diferida \xe9 a vers\xe3o mais dif\xedcil e mais informativa, e vale a pena pratic\xe1-la de prop\xf3sito.",research:"O que est\xe1 solidamente demonstrado \xe9 estreito: pratique o recordar de hist\xf3rias e voc\xea melhora no recordar de hist\xf3rias, e o treino estruturado de estrat\xe9gias de mem\xf3ria melhora de forma fi\xe1vel o desempenho nas tarefas treinadas e em tarefas muito semelhantes (transfer\xeancia pr\xf3xima). As alega\xe7\xf5es amplas s\xe3o bem mais fracas \u2014 que eleva a intelig\xeancia geral, agu\xe7a a mem\xf3ria do dia a dia n\xe3o relacionada ou previne o decl\xednio ligado \xe0 idade \xe9 em grande parte n\xe3o comprovado, e as grandes revis\xf5es sobre treino cerebral continuam a constatar que os ganhos raramente se estendem muito al\xe9m da habilidade praticada. Encare-o como um exerc\xedcio honesto para a mem\xf3ria verbal, n\xe3o como cura para o esquecimento.",rec:"Depois da primeira leitura, reconte a hist\xf3ria com as suas pr\xf3prias palavras antes de conferir \u2014 testar-se a si mesmo fixa muito mais do que reler.",faq:[["Isto \xe9 o mesmo que o teste de Mem\xf3ria L\xf3gica que os m\xe9dicos usam?","Usa o mesmo formato \u2014 recordar uma hist\xf3ria curta logo de imediato e depois de um intervalo \u2014 mas como pr\xe1tica do dia a dia, n\xe3o como avalia\xe7\xe3o cl\xednica. As vers\xf5es de teste s\xe3o padronizadas e pontuadas por profissionais; um treinador apenas deixa voc\xea exercitar a mesma habilidade."],["Vai melhorar a minha mem\xf3ria em geral?","Vai torn\xe1-lo de forma fi\xe1vel melhor a lembrar hist\xf3rias e material semelhante. Uma melhoria ampla da mem\xf3ria do dia a dia n\xe3o relacionada n\xe3o \xe9 bem sustentada pela evid\xeancia, ent\xe3o espere ganhos pr\xf3ximos daquilo que voc\xea de fato pratica."],["Devo decorar as palavras exatas?","N\xe3o. Vise o sentido e os detalhes concretos \u2014 o que aconteceu, a quem, os nomes e os n\xfameros. A pontua\xe7\xe3o detalhe por detalhe recompensa o conte\xfado correto, e a recorda\xe7\xe3o baseada no sentido aguenta-se muito melhor do que decorar palavra por palavra."]],variants:"Varie a carga pelo comprimento da hist\xf3ria e pela densidade de nomes, n\xfameros e datas. Alterne entre ler e ouvir, entre recorda\xe7\xe3o imediata e diferida (20 a 30 minutos) e entre recontagem livre e responder a perguntas espec\xedficas sobre o trecho; recordar os acontecimentos rigorosamente em ordem \xe9 um modo ainda mais dif\xedcil."},hi:{about:"\u0906\u092a \u090f\u0915 \u091b\u094b\u091f\u0940 \u0915\u0939\u093e\u0928\u0940 \u090f\u0915 \u092c\u093e\u0930 \u092a\u0922\u093c\u0924\u0947 \u092f\u093e \u0938\u0941\u0928\u0924\u0947 \u0939\u0948\u0902, \u092b\u093f\u0930 \u0909\u0938\u0947 \u0938\u094d\u092e\u0943\u0924\u093f \u0938\u0947 \u0926\u094b\u092c\u093e\u0930\u093e \u0916\u0921\u093c\u093e \u0915\u0930\u0924\u0947 \u0939\u0948\u0902 \u2014 \u091c\u093f\u0924\u0928\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0920\u094b\u0938 \u092c\u094d\u092f\u094b\u0930\u0947 \u0939\u094b \u0938\u0915\u0947\u0902 \u092f\u093e\u0926 \u0915\u0930\u0924\u0947 \u0939\u0941\u090f: \u0928\u093e\u092e, \u0938\u0902\u0916\u094d\u092f\u093e\u090f\u0901, \u091c\u0917\u0939\u0947\u0902, \u0918\u091f\u0928\u093e\u0913\u0902 \u0915\u093e \u0915\u094d\u0930\u092e\u0964 \u0938\u094d\u0915\u094b\u0930\u093f\u0902\u0917 \u092e\u0947\u0902 \u092f\u0939 \u0917\u093f\u0928\u093e \u091c\u093e\u0924\u093e \u0939\u0948 \u0915\u093f \u0906\u092a\u0928\u0947 \u0915\u0939\u093e\u0928\u0940 \u0915\u0947 \u0915\u094c\u0928-\u0915\u094c\u0928 \u0938\u0947 \u0916\u093e\u0938 \u0924\u0924\u094d\u0935 \u0935\u093e\u092a\u0938 \u0932\u093e\u090f, \u0928 \u0915\u093f \u0932\u0947\u0916\u0928 \u0915\u093f\u0924\u0928\u093e \u0905\u091a\u094d\u091b\u093e \u0939\u0948 \u2014 \u0907\u0938\u0932\u093f\u090f \u092a\u0942\u0930\u093e \u0939\u0941\u0928\u0930 \u0915\u093f\u0938\u0940 \u090f\u0915 \u0915\u0925\u093e \u0915\u0947 \u0924\u0925\u094d\u092f\u094b\u0902 \u0915\u094b \u092a\u0915\u0921\u093c\u0928\u0947 \u0914\u0930 \u0925\u093e\u092e\u0947 \u0930\u0916\u0928\u0947 \u092e\u0947\u0902 \u0939\u0948\u0964",benefit:"\u092f\u0939 \u092e\u094c\u0916\u093f\u0915 \u092a\u094d\u0930\u093e\u0938\u0902\u0917\u093f\u0915 (episodic) \u0938\u094d\u092e\u0943\u0924\u093f \u0915\u094b \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u093f\u0924 \u0915\u0930\u0924\u093e \u0939\u0948: \u0938\u093e\u0930\u094d\u0925\u0915 \u0917\u0926\u094d\u092f \u0915\u094b \u090f\u0928\u094d\u0915\u094b\u0921 \u0915\u0930\u0928\u093e, \u0909\u0938\u0947 \u0925\u094b\u0921\u093c\u0940 \u0926\u0947\u0930 \u0925\u093e\u092e\u0928\u093e, \u0914\u0930 \u092c\u094d\u092f\u094b\u0930\u094b\u0902 \u0915\u094b \u0938\u091f\u0940\u0915 \u0930\u0942\u092a \u0938\u0947 \u0935\u093e\u092a\u0938 \u0932\u093e\u0928\u093e\u0964 \u091a\u0942\u0901\u0915\u093f \u0915\u0939\u093e\u0928\u0940 \u0915\u093f\u0938\u0940 \u092c\u0947\u0924\u0930\u0924\u0940\u092c \u0938\u0942\u091a\u0940 \u0915\u0947 \u092c\u091c\u093e\u092f \u0906\u092a\u0938 \u092e\u0947\u0902 \u091c\u0941\u0921\u093c\u0940 \u0939\u094b\u0924\u0940 \u0939\u0948, \u092f\u0939 \u0909\u0938 \u0924\u0930\u0940\u0915\u0947 \u0915\u093e \u092d\u0940 \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0930\u093e\u0924\u0940 \u0939\u0948 \u091c\u093f\u0938\u0938\u0947 \u0906\u092a \u0924\u0925\u094d\u092f\u094b\u0902 \u0915\u094b \u090f\u0915 \u0938\u0941\u0938\u0902\u0917\u0924 \u0922\u093e\u0901\u091a\u0947 \u092e\u0947\u0902 \u092c\u093e\u0901\u0927\u0924\u0947 \u0939\u0948\u0902 \u0914\u0930 \u0909\u0928\u094d\u0939\u0947\u0902 \u0915\u094d\u0930\u092e \u092e\u0947\u0902 \u0935\u093e\u092a\u0938 \u0932\u093e\u0924\u0947 \u0939\u0948\u0902\u0964",history:"\u091c\u093c\u094b\u0930 \u0938\u0947 \u092a\u0922\u093c\u0947 \u0917\u090f \u0915\u093f\u0938\u0940 \u0905\u0902\u0936 \u0915\u094b \u092f\u093e\u0926 \u0915\u0930\u0928\u093e \u0938\u094d\u092e\u0943\u0924\u093f-\u092a\u0930\u0940\u0915\u094d\u0937\u0923 \u0915\u0947 \u0938\u092c\u0938\u0947 \u092a\u0941\u0930\u093e\u0928\u0947 \u092a\u094d\u0930\u093e\u0930\u0942\u092a\u094b\u0902 \u092e\u0947\u0902 \u0938\u0947 \u090f\u0915 \u0939\u0948\u0964 Harriet Babcock \u0928\u0947 \u092e\u093e\u0928\u0938\u093f\u0915 \u0939\u094d\u0930\u093e\u0938 \u092a\u0930 \u0905\u092a\u0928\u0947 1930 \u0915\u0947 \u0915\u093e\u092e \u092e\u0947\u0902 \u091b\u094b\u091f\u0940 \u0915\u0939\u093e\u0928\u0940 \u0915\u0940 \u092a\u0941\u0928\u0903\u0938\u094d\u092e\u0943\u0924\u093f \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0915\u0940, \u0914\u0930 David Wechsler \u0928\u0947 1945 \u092e\u0947\u0902 Wechsler Memory Scale \u092e\u0947\u0902 \u090f\u0915 'Logical Memory' \u0915\u0939\u093e\u0928\u0940-\u092a\u0941\u0928\u0903\u0938\u094d\u092e\u0943\u0924\u093f \u0915\u093e\u0930\u094d\u092f \u0917\u0922\u093c\u093e; \u0935\u0939 \u0909\u092a-\u092a\u0930\u0940\u0915\u094d\u0937\u0923, \u0924\u0924\u094d\u0915\u093e\u0932 \u0914\u0930 \u0935\u093f\u0932\u0902\u092c\u093f\u0924 \u092a\u0941\u0928\u0930\u094d\u0915\u0925\u0928 \u0915\u0947 \u0938\u093e\u0925, \u0939\u0930 \u092c\u093e\u0926 \u0915\u0947 \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u092e\u0947\u0902 \u092c\u0928\u093e \u0930\u0939\u093e \u0914\u0930 \u0906\u091c \u092d\u0940 \u0915\u094d\u0932\u093f\u0928\u093f\u0915\u094b\u0902 \u092e\u0947\u0902 \u092e\u093e\u0928\u0915 \u0939\u0948\u0964",creator:"\u0907\u0938 \u0916\u0947\u0932 \u0915\u093e \u0915\u094b\u0908 \u090f\u0915 \u0906\u0935\u093f\u0937\u094d\u0915\u093e\u0930\u0915 \u0928\u0939\u0940\u0902 \u0939\u0948\u0964 \u092f\u0939 \u0915\u094d\u0932\u093f\u0928\u093f\u0915\u0932 \u0915\u0939\u093e\u0928\u0940-\u092a\u0941\u0928\u0903\u0938\u094d\u092e\u0943\u0924\u093f \u0915\u0940 \u092a\u0930\u0902\u092a\u0930\u093e \u0938\u0947 \u0909\u0924\u0930\u093e \u0939\u0948 \u2014 Harriet Babcock \u0915\u093e 1930 \u0915\u093e \u092e\u093e\u0928\u0938\u093f\u0915-\u0939\u094d\u0930\u093e\u0938 \u0935\u093e\u0932\u093e \u0915\u093e\u092e \u0914\u0930, \u0938\u092c\u0938\u0947 \u092a\u094d\u0930\u092d\u093e\u0935\u0936\u093e\u0932\u0940 \u0930\u0942\u092a \u0938\u0947, David Wechsler \u0915\u093e Wechsler Memory Scale (1945) \u0935\u093e\u0932\u093e Logical Memory \u0909\u092a-\u092a\u0930\u0940\u0915\u094d\u0937\u0923\u0964 \u092f\u0939 \u091f\u094d\u0930\u0947\u0928\u0930 \u0909\u0938\u0940 \u0932\u0902\u092c\u0947-\u0938\u094d\u0925\u093e\u092a\u093f\u0924 \u092a\u094d\u0930\u093e\u0930\u0942\u092a \u0915\u093e \u090f\u0915 \u0905\u092d\u094d\u092f\u093e\u0938-\u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0939\u0948, \u0915\u094b\u0908 \u092c\u094d\u0930\u093e\u0902\u0921\u0947\u0921 \u0906\u0935\u093f\u0937\u094d\u0915\u093e\u0930 \u0928\u0939\u0940\u0902\u0964",methods:"\u092a\u0939\u0932\u0940 \u092c\u093e\u0930 \u092e\u0947\u0902 \u0915\u0939\u093e\u0928\u0940 \u0915\u0940 \u0930\u0940\u0922\u093c \u0938\u0941\u0928\u0947\u0902 \u2014 \u0915\u094c\u0928, \u0915\u0939\u093e\u0901, \u0914\u0930 \u0915\u094d\u092f\u093e \u092c\u0926\u0932\u093e \u2014 \u092b\u093f\u0930 \u0916\u093e\u0938 \u092c\u094d\u092f\u094b\u0930\u0947 (\u0938\u0902\u0916\u094d\u092f\u093e\u090f\u0901, \u0928\u093e\u092e) \u0909\u0938\u0940 \u0922\u093e\u0901\u091a\u0947 \u092a\u0930 \u091f\u093e\u0901\u0917 \u0926\u0947\u0902\u0964 \u0926\u0943\u0936\u094d\u092f \u0915\u094b \u091c\u0948\u0938\u0947-\u091c\u0948\u0938\u0947 \u0935\u0939 \u0916\u0941\u0932\u0924\u093e \u0939\u0948 \u0935\u0948\u0938\u0947-\u0935\u0948\u0938\u0947 \u092e\u0928 \u092e\u0947\u0902 \u0926\u0947\u0916\u0947\u0902 \u0914\u0930 \u0936\u092c\u094d\u0926 \u0930\u091f\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u0924\u0925\u094d\u092f\u094b\u0902 \u0915\u094b \u0915\u093e\u0930\u0923-\u0914\u0930-\u092a\u0930\u093f\u0923\u093e\u092e \u092e\u0947\u0902 \u091c\u094b\u0921\u093c\u0947\u0902; \u0920\u0940\u0915 \u092c\u093e\u0926, \u091c\u093e\u0901\u091a\u0928\u0947 \u0938\u0947 \u092a\u0939\u0932\u0947 \u0939\u0940 \u0909\u0938\u0947 \u091c\u093c\u094b\u0930 \u0938\u0947 \u092f\u093e \u0932\u093f\u0916\u0915\u0930 \u0926\u094b\u092c\u093e\u0930\u093e \u0938\u0941\u0928\u093e\u090f\u0901, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u0935\u093e\u092a\u0938 \u0932\u093e\u0928\u0947 \u0915\u0940 \u092f\u0939\u0940 \u0915\u094d\u0930\u093f\u092f\u093e \u0938\u094d\u092e\u0943\u0924\u093f \u0915\u094b \u092e\u091c\u093c\u092c\u0942\u0924 \u0915\u0930\u0924\u0940 \u0939\u0948\u0964",duration:"\u091b\u094b\u091f\u0947 \u0938\u0924\u094d\u0930 \u0938\u092c\u0938\u0947 \u0905\u091a\u094d\u091b\u0947 \u0930\u0939\u0924\u0947 \u0939\u0948\u0902: \u0915\u0941\u091b\u0947\u0915 \u0915\u0939\u093e\u0928\u093f\u092f\u093e\u0901, \u0915\u0930\u0940\u092c 10 \u0938\u0947 15 \u092e\u093f\u0928\u091f, \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u0915\u0941\u091b\u0947\u0915 \u092c\u093e\u0930\u0964 \u092c\u0940\u091a-\u092c\u0940\u091a \u092e\u0947\u0902 20 \u0938\u0947 30 \u092e\u093f\u0928\u091f \u092c\u093e\u0926 \u090f\u0915 \u0935\u093f\u0932\u0902\u092c\u093f\u0924 \u092a\u0941\u0928\u0930\u094d\u0915\u0925\u0928 \u091c\u094b\u0921\u093c\u0947\u0902 \u2014 \u0935\u093f\u0932\u0902\u092c\u093f\u0924 \u092a\u0941\u0928\u0903\u0938\u094d\u092e\u0943\u0924\u093f \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0915\u0920\u093f\u0928 \u0914\u0930 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u091c\u093e\u0928\u0915\u093e\u0930\u0940 \u0926\u0947\u0928\u0947 \u0935\u093e\u0932\u093e \u0930\u0942\u092a \u0939\u0948 \u0914\u0930 \u0907\u0938\u0947 \u091c\u093e\u0928-\u092c\u0942\u091d\u0915\u0930 \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0930\u0928\u093e \u0938\u0939\u0940 \u0930\u0939\u0924\u093e \u0939\u0948\u0964",research:"\u091c\u094b \u092c\u093e\u0924 \u092a\u0941\u0916\u093c\u094d\u0924\u093e \u0924\u0930\u0940\u0915\u0947 \u0938\u0947 \u0926\u093f\u0916\u0924\u0940 \u0939\u0948 \u0935\u0939 \u0938\u0940\u092e\u093f\u0924 \u0939\u0948: \u0915\u0939\u093e\u0928\u0940-\u092a\u0941\u0928\u0903\u0938\u094d\u092e\u0943\u0924\u093f \u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0930\u0947\u0902 \u0914\u0930 \u0906\u092a \u0915\u0939\u093e\u0928\u0940-\u092a\u0941\u0928\u0903\u0938\u094d\u092e\u0943\u0924\u093f \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u0938\u0902\u0930\u091a\u093f\u0924 \u0938\u094d\u092e\u0943\u0924\u093f-\u0930\u0923\u0928\u0940\u0924\u093f \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0930\u0942\u092a \u0938\u0947 \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u093f\u0924 \u0914\u0930 \u092c\u0947\u0939\u0926 \u092e\u093f\u0932\u0924\u0947-\u091c\u0941\u0932\u0924\u0947 \u0915\u093e\u0930\u094d\u092f\u094b\u0902 (\u0928\u093f\u0915\u091f \u0938\u094d\u0925\u093e\u0928\u093e\u0902\u0924\u0930\u0923) \u092a\u0930 \u092a\u094d\u0930\u0926\u0930\u094d\u0936\u0928 \u0938\u0941\u0927\u093e\u0930\u0924\u093e \u0939\u0948\u0964 \u0935\u094d\u092f\u093e\u092a\u0915 \u0926\u093e\u0935\u0947 \u0915\u0939\u0940\u0902 \u0915\u092e\u091c\u093c\u094b\u0930 \u0939\u0948\u0902 \u2014 \u0915\u093f \u092f\u0939 \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u092c\u0941\u0926\u094d\u0927\u093f \u092c\u0922\u093c\u093e\u0924\u093e \u0939\u0948, \u0905\u0938\u0902\u092c\u0902\u0927\u093f\u0924 \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0940 \u0938\u094d\u092e\u0943\u0924\u093f \u0915\u094b \u092a\u0948\u0928\u093e \u0915\u0930\u0924\u093e \u0939\u0948, \u092f\u093e \u0909\u092e\u094d\u0930-\u0938\u0902\u092c\u0902\u0927\u0940 \u0917\u093f\u0930\u093e\u0935\u091f \u0930\u094b\u0915\u0924\u093e \u0939\u0948, \u092f\u0939 \u091c\u093c\u094d\u092f\u093e\u0926\u093e\u0924\u0930 \u0905\u092a\u094d\u0930\u092e\u093e\u0923\u093f\u0924 \u0939\u0948, \u0914\u0930 \u092c\u094d\u0930\u0947\u0928 \u091f\u094d\u0930\u0947\u0928\u093f\u0902\u0917 \u0915\u0940 \u092c\u0921\u093c\u0940 \u0938\u092e\u0940\u0915\u094d\u0937\u093e\u090f\u0901 \u092c\u093e\u0930-\u092c\u093e\u0930 \u092a\u093e\u0924\u0940 \u0939\u0948\u0902 \u0915\u093f \u092b\u093c\u093e\u092f\u0926\u0947 \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u093f\u090f \u0915\u094c\u0936\u0932 \u0938\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0926\u0942\u0930 \u0936\u093e\u092f\u0926 \u0939\u0940 \u092b\u0948\u0932\u0924\u0947 \u0939\u0948\u0902\u0964 \u0907\u0938\u0947 \u092e\u094c\u0916\u093f\u0915 \u0938\u094d\u092e\u0943\u0924\u093f \u0915\u0940 \u090f\u0915 \u0908\u092e\u093e\u0928\u0926\u093e\u0930 \u0915\u0938\u0930\u0924 \u092e\u093e\u0928\u0947\u0902, \u092d\u0941\u0932\u0915\u094d\u0915\u0921\u093c\u092a\u0928 \u0915\u093e \u0907\u0932\u093e\u091c \u0928\u0939\u0940\u0902\u0964",rec:"\u092a\u0939\u0932\u0940 \u092c\u093e\u0930 \u092a\u0922\u093c\u0928\u0947 \u0915\u0947 \u092c\u093e\u0926, \u091c\u093e\u0901\u091a\u0928\u0947 \u0938\u0947 \u092a\u0939\u0932\u0947 \u0915\u0939\u093e\u0928\u0940 \u0915\u094b \u0905\u092a\u0928\u0947 \u0936\u092c\u094d\u0926\u094b\u0902 \u092e\u0947\u0902 \u0926\u094b\u092c\u093e\u0930\u093e \u0938\u0941\u0928\u093e\u090f\u0901 \u2014 \u0916\u0941\u0926 \u0915\u094b \u092a\u0930\u0916\u0928\u093e \u0926\u094b\u092c\u093e\u0930\u093e \u092a\u0922\u093c\u0928\u0947 \u0938\u0947 \u0915\u0939\u0940\u0902 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u092c\u093e\u0924\u0947\u0902 \u092a\u0915\u094d\u0915\u0940 \u0915\u0930 \u0926\u0947\u0924\u093e \u0939\u0948\u0964",faq:[["\u0915\u094d\u092f\u093e \u092f\u0939 \u0935\u0939\u0940 Logical Memory \u092a\u0930\u0940\u0915\u094d\u0937\u0923 \u0939\u0948 \u091c\u094b \u0921\u0949\u0915\u094d\u091f\u0930 \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902?","\u092f\u0939 \u0935\u0939\u0940 \u092a\u094d\u0930\u093e\u0930\u0942\u092a \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0915\u0930\u0924\u093e \u0939\u0948 \u2014 \u090f\u0915 \u091b\u094b\u091f\u0940 \u0915\u0939\u093e\u0928\u0940 \u0924\u0941\u0930\u0902\u0924 \u0914\u0930 \u090f\u0915 \u0926\u0947\u0930\u0940 \u0915\u0947 \u092c\u093e\u0926 \u092f\u093e\u0926 \u0915\u0930\u0928\u093e \u2014 \u092a\u0930 \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0947 \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0947 \u0924\u094c\u0930 \u092a\u0930, \u0915\u093f\u0938\u0940 \u0915\u094d\u0932\u093f\u0928\u093f\u0915\u0932 \u0906\u0915\u0932\u0928 \u0915\u0947 \u0924\u094c\u0930 \u092a\u0930 \u0928\u0939\u0940\u0902\u0964 \u092a\u0930\u0940\u0915\u094d\u0937\u0923-\u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u092e\u093e\u0928\u0915\u0940\u0915\u0943\u0924 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902 \u0914\u0930 \u092a\u0947\u0936\u0947\u0935\u0930\u094b\u0902 \u0926\u094d\u0935\u093e\u0930\u093e \u0938\u094d\u0915\u094b\u0930 \u0915\u093f\u090f \u091c\u093e\u0924\u0947 \u0939\u0948\u0902; \u091f\u094d\u0930\u0947\u0928\u0930 \u0924\u094b \u092c\u0938 \u0906\u092a\u0915\u094b \u0909\u0938\u0940 \u0939\u0941\u0928\u0930 \u0915\u0940 \u0915\u0938\u0930\u0924 \u0915\u0930\u0928\u0947 \u0926\u0947\u0924\u093e \u0939\u0948\u0964"],["\u0915\u094d\u092f\u093e \u092f\u0939 \u092e\u0947\u0930\u0940 \u0938\u094d\u092e\u0943\u0924\u093f \u0915\u094b \u0915\u0941\u0932 \u092e\u093f\u0932\u093e\u0915\u0930 \u0938\u0941\u0927\u093e\u0930 \u0926\u0947\u0917\u093e?","\u092f\u0939 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0930\u0942\u092a \u0938\u0947 \u0906\u092a\u0915\u094b \u0915\u0939\u093e\u0928\u093f\u092f\u093e\u0901 \u0914\u0930 \u092e\u093f\u0932\u0924\u0940-\u091c\u0941\u0932\u0924\u0940 \u0938\u093e\u092e\u0917\u094d\u0930\u0940 \u092f\u093e\u0926 \u0930\u0916\u0928\u0947 \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u092c\u0928\u093e \u0926\u0947\u0917\u093e\u0964 \u0905\u0938\u0902\u092c\u0902\u0927\u093f\u0924, \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0940 \u0938\u094d\u092e\u0943\u0924\u093f \u092e\u0947\u0902 \u0935\u094d\u092f\u093e\u092a\u0915 \u0909\u091b\u093e\u0932 \u0915\u094b \u0938\u092c\u0942\u0924 \u0905\u091a\u094d\u091b\u0940 \u0924\u0930\u0939 \u0938\u0939\u093e\u0930\u093e \u0928\u0939\u0940\u0902 \u0926\u0947\u0924\u0947, \u0907\u0938\u0932\u093f\u090f \u0909\u0924\u0928\u0947 \u0939\u0940 \u092b\u093c\u093e\u092f\u0926\u0947 \u0915\u0940 \u0909\u092e\u094d\u092e\u0940\u0926 \u0930\u0916\u0947\u0902 \u091c\u093f\u0924\u0928\u093e \u0906\u092a \u0905\u0938\u0932 \u092e\u0947\u0902 \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902\u0964"],["\u0915\u094d\u092f\u093e \u092e\u0941\u091d\u0947 \u0939\u0942-\u092c-\u0939\u0942 \u0936\u092c\u094d\u0926 \u092f\u093e\u0926 \u0915\u0930\u0928\u0947 \u091a\u093e\u0939\u093f\u090f?","\u0928\u0939\u0940\u0902\u0964 \u092e\u0924\u0932\u092c \u0914\u0930 \u0920\u094b\u0938 \u092c\u094d\u092f\u094b\u0930\u094b\u0902 \u0915\u093e \u0932\u0915\u094d\u0937\u094d\u092f \u0930\u0916\u0947\u0902 \u2014 \u0915\u094d\u092f\u093e \u0939\u0941\u0906, \u0915\u093f\u0938\u0915\u0947 \u0938\u093e\u0925, \u0928\u093e\u092e \u0914\u0930 \u0938\u0902\u0916\u094d\u092f\u093e\u090f\u0901\u0964 \u092c\u094d\u092f\u094b\u0930\u0947-\u0926\u0930-\u092c\u094d\u092f\u094b\u0930\u0947 \u0938\u094d\u0915\u094b\u0930\u093f\u0902\u0917 \u0938\u091f\u0940\u0915 \u0938\u093e\u092e\u0917\u094d\u0930\u0940 \u0915\u094b \u0907\u0928\u093e\u092e \u0926\u0947\u0924\u0940 \u0939\u0948, \u0914\u0930 \u0905\u0930\u094d\u0925-\u0906\u0927\u093e\u0930\u093f\u0924 \u092a\u0941\u0928\u0903\u0938\u094d\u092e\u0943\u0924\u093f \u0936\u092c\u094d\u0926-\u0926\u0930-\u0936\u092c\u094d\u0926 \u0930\u091f\u0928\u0947 \u0938\u0947 \u0915\u0939\u0940\u0902 \u092c\u0947\u0939\u0924\u0930 \u091f\u093f\u0915\u0924\u0940 \u0939\u0948\u0964"]],variants:"\u0915\u0939\u093e\u0928\u0940 \u0915\u0940 \u0932\u0902\u092c\u093e\u0908 \u0914\u0930 \u0928\u093e\u092e\u094b\u0902, \u0938\u0902\u0916\u094d\u092f\u093e\u0913\u0902 \u0924\u0925\u093e \u0924\u093e\u0930\u0940\u0916\u093c\u094b\u0902 \u0915\u0947 \u0918\u0928\u0924\u094d\u0935 \u0938\u0947 \u092d\u093e\u0930 \u092c\u0926\u0932\u0947\u0902\u0964 \u092a\u0922\u093c\u0928\u0947 \u0914\u0930 \u0938\u0941\u0928\u0928\u0947 \u0915\u0947 \u092c\u0940\u091a, \u0924\u0924\u094d\u0915\u093e\u0932 \u0914\u0930 \u0935\u093f\u0932\u0902\u092c\u093f\u0924 (20\u201330 \u092e\u093f\u0928\u091f) \u092a\u0941\u0928\u0903\u0938\u094d\u092e\u0943\u0924\u093f \u0915\u0947 \u092c\u0940\u091a, \u0914\u0930 \u0938\u094d\u0935\u0924\u0902\u0924\u094d\u0930 \u092a\u0941\u0928\u0930\u094d\u0915\u0925\u0928 \u0924\u0925\u093e \u0905\u0902\u0936 \u0915\u0947 \u092c\u093e\u0930\u0947 \u092e\u0947\u0902 \u0916\u093e\u0938 \u0938\u0935\u093e\u0932\u094b\u0902 \u0915\u0947 \u091c\u0935\u093e\u092c \u0926\u0947\u0928\u0947 \u0915\u0947 \u092c\u0940\u091a \u0905\u0926\u0932\u093e-\u092c\u0926\u0932\u0940 \u0915\u0930\u0947\u0902; \u0918\u091f\u0928\u093e\u0913\u0902 \u0915\u094b \u0938\u0916\u093c\u094d\u0924\u0940 \u0938\u0947 \u0915\u094d\u0930\u092e \u092e\u0947\u0902 \u092f\u093e\u0926 \u0915\u0930\u0928\u093e \u092b\u093f\u0930 \u0938\u0947 \u090f\u0915 \u0914\u0930 \u0915\u0920\u093f\u0928 \u0922\u0902\u0917 \u0939\u0948\u0964"},zh:{about:"\u4f60\u628a\u4e00\u4e2a\u77ed\u7bc7\u6545\u4e8b\u8bfb\u4e00\u904d\u6216\u542c\u4e00\u904d\uff0c\u7136\u540e\u51ed\u8bb0\u5fc6\u628a\u5b83\u590d\u8ff0\u51fa\u6765\uff0c\u5c3d\u91cf\u591a\u5730\u56de\u60f3\u5177\u4f53\u7ec6\u8282\u2014\u2014\u4eba\u540d\u3001\u6570\u5b57\u3001\u5730\u70b9\u3001\u4e8b\u4ef6\u7684\u5148\u540e\u987a\u5e8f\u3002\u8bc4\u5206\u6570\u7684\u662f\u4f60\u6210\u529f\u627e\u56de\u7684\u90a3\u4e9b\u5177\u4f53\u6545\u4e8b\u8981\u7d20\uff0c\u800c\u4e0d\u662f\u6587\u7b14\u597d\u574f\uff0c\u6240\u4ee5\u5168\u90e8\u6280\u80fd\u90fd\u5728\u4e8e\u6355\u6349\u5e76\u5b88\u4f4f\u4e00\u4e2a\u6545\u4e8b\u91cc\u7684\u4e8b\u5b9e\u3002",benefit:"\u5b83\u8bad\u7ec3\u8a00\u8bed\u60c5\u666f\u8bb0\u5fc6\uff1a\u5bf9\u6709\u610f\u4e49\u7684\u6563\u6587\u8fdb\u884c\u7f16\u7801\u3001\u77ed\u6682\u4fdd\u6301\u3001\u518d\u51c6\u786e\u5730\u628a\u7ec6\u8282\u63d0\u53d6\u51fa\u6765\u3002\u7531\u4e8e\u6545\u4e8b\u662f\u8fde\u8d2f\u7684\uff0c\u800c\u4e0d\u662f\u4e00\u4e32\u968f\u673a\u6e05\u5355\uff0c\u5b83\u8fd8\u4f1a\u953b\u70bc\u4f60\u628a\u4e8b\u5b9e\u7ed1\u6210\u4e00\u4e2a\u8fde\u8d2f\u7ed3\u6784\u3001\u5e76\u6309\u987a\u5e8f\u627e\u56de\u5b83\u4eec\u7684\u65b9\u5f0f\u3002",history:"\u590d\u8ff0\u4e00\u6bb5\u6717\u8bfb\u8fc7\u7684\u6587\u5b57\uff0c\u662f\u8bb0\u5fc6\u6d4b\u9a8c\u4e2d\u6700\u53e4\u8001\u7684\u5f62\u5f0f\u4e4b\u4e00\u3002Harriet Babcock \u5728\u5979 1930 \u5e74\u5173\u4e8e\u5fc3\u667a\u8870\u9000\u7684\u7814\u7a76\u4e2d\u4f7f\u7528\u4e86\u77ed\u7bc7\u6545\u4e8b\u590d\u8ff0\uff0c\u800c David Wechsler \u4e8e 1945 \u5e74\u628a\u4e00\u9879\u300c\u903b\u8f91\u8bb0\u5fc6\u300d\u6545\u4e8b\u590d\u8ff0\u4efb\u52a1\u7eb3\u5165\u4e86\u97e6\u6c0f\u8bb0\u5fc6\u91cf\u8868\uff1b\u90a3\u4e2a\u5206\u6d4b\u9a8c\uff0c\u8fde\u540c\u5373\u65f6\u548c\u5ef6\u8fdf\u590d\u8ff0\uff0c\u5728\u540e\u6765\u6bcf\u4e00\u4e2a\u7248\u672c\u4e2d\u90fd\u4fdd\u7559\u4e86\u4e0b\u6765\uff0c\u81f3\u4eca\u4ecd\u662f\u8bca\u6240\u7684\u6807\u51c6\u3002",creator:"\u8fd9\u4e2a\u6e38\u620f\u6ca1\u6709\u5355\u4e00\u7684\u53d1\u660e\u8005\u3002\u5b83\u6e90\u81ea\u4e34\u5e8a\u6545\u4e8b\u590d\u8ff0\u4f20\u7edf\u2014\u2014Harriet Babcock 1930 \u5e74\u7684\u5fc3\u667a\u8870\u9000\u7814\u7a76\uff0c\u4ee5\u53ca\u5f71\u54cd\u6700\u5927\u7684\u3001David Wechsler \u97e6\u6c0f\u8bb0\u5fc6\u91cf\u8868\uff081945 \u5e74\uff09\u4e2d\u7684\u903b\u8f91\u8bb0\u5fc6\u5206\u6d4b\u9a8c\u3002\u8fd9\u4e2a\u8bad\u7ec3\u5668\u662f\u90a3\u5957\u65e9\u5df2\u786e\u7acb\u7684\u5f62\u5f0f\u7684\u7ec3\u4e60\u7248\uff0c\u800c\u975e\u67d0\u4e2a\u5e26\u5546\u6807\u7684\u53d1\u660e\u3002",methods:"\u7b2c\u4e00\u904d\u65f6\uff0c\u53bb\u542c\u51fa\u6545\u4e8b\u7684\u810a\u6881\u2014\u2014\u8c01\u3001\u5728\u54ea\u3001\u53d1\u751f\u4e86\u4ec0\u4e48\u53d8\u5316\u2014\u2014\u7136\u540e\u628a\u5177\u4f53\u7ec6\u8282\uff08\u6570\u5b57\u3001\u4eba\u540d\uff09\u6302\u5230\u90a3\u4e2a\u6846\u67b6\u4e0a\u3002\u628a\u573a\u666f\u968f\u60c5\u8282\u5c55\u5f00\u60f3\u8c61\u51fa\u6765\uff0c\u628a\u4e8b\u5b9e\u4e32\u6210\u56e0\u679c\uff0c\u800c\u4e0d\u662f\u53bb\u80cc\u8bcd\u53e5\uff1b\u8bfb\u5b8c\u540e\u7acb\u523b\u5728\u6838\u5bf9\u4e4b\u524d\u5148\u5927\u58f0\u6216\u4e66\u9762\u590d\u8ff0\u4e00\u904d\uff0c\u56e0\u4e3a\u6b63\u662f\u300c\u63d0\u53d6\u300d\u8fd9\u4e2a\u52a8\u4f5c\u5728\u5f3a\u5316\u8bb0\u5fc6\u3002",duration:"\u77ed\u65f6\u6bb5\u7ec3\u4e60\u6548\u679c\u6700\u597d\uff1a\u51e0\u4e2a\u6545\u4e8b\uff0c\u5927\u7ea6 10 \u5230 15 \u5206\u949f\uff0c\u6bcf\u5468\u51e0\u6b21\u3002\u65f6\u4e0d\u65f6\u5728 20 \u5230 30 \u5206\u949f\u540e\u518d\u52a0\u4e00\u6b21\u5ef6\u8fdf\u590d\u8ff0\u2014\u2014\u5ef6\u8fdf\u56de\u5fc6\u662f\u66f4\u96be\u3001\u4fe1\u606f\u91cf\u66f4\u5927\u7684\u7248\u672c\uff0c\u503c\u5f97\u523b\u610f\u53bb\u7ec3\u3002",research:"\u88ab\u7a33\u56fa\u8bc1\u660e\u7684\u8303\u56f4\u5f88\u7a84\uff1a\u7ec3\u6545\u4e8b\u590d\u8ff0\uff0c\u4f60\u5c31\u4f1a\u5728\u6545\u4e8b\u590d\u8ff0\u4e0a\u53d8\u597d\uff0c\u800c\u7ed3\u6784\u5316\u7684\u8bb0\u5fc6\u7b56\u7565\u8bad\u7ec3\u80fd\u53ef\u9760\u5730\u6539\u5584\u53d7\u8bad\u4efb\u52a1\u53ca\u4e0e\u4e4b\u9ad8\u5ea6\u76f8\u4f3c\u4efb\u52a1\u4e0a\u7684\u8868\u73b0\uff08\u8fd1\u8fc1\u79fb\uff09\u3002\u66f4\u5bbd\u6cdb\u7684\u8bf4\u6cd5\u8981\u5f31\u5f97\u591a\u2014\u2014\u5b83\u80fd\u63d0\u5347\u4e00\u822c\u667a\u529b\u3001\u78e8\u5feb\u65e0\u5173\u7684\u65e5\u5e38\u8bb0\u5fc6\uff0c\u6216\u9884\u9632\u5e74\u9f84\u76f8\u5173\u7684\u8870\u9000\uff0c\u8fd9\u4e9b\u57fa\u672c\u672a\u88ab\u8bc1\u5b9e\uff0c\u800c\u5927\u578b\u7684\u5927\u8111\u8bad\u7ec3\u7efc\u8ff0\u4e00\u518d\u53d1\u73b0\uff0c\u6536\u76ca\u5f88\u5c11\u6269\u6563\u5230\u7ec3\u4e60\u8fc7\u7684\u6280\u80fd\u4e4b\u5916\u3002\u628a\u5b83\u5f53\u4f5c\u5bf9\u8a00\u8bed\u8bb0\u5fc6\u7684\u8bda\u5b9e\u953b\u70bc\uff0c\u800c\u4e0d\u662f\u5065\u5fd8\u7684\u89e3\u836f\u3002",rec:"\u7b2c\u4e00\u904d\u8bfb\u5b8c\u540e\uff0c\u5148\u7528\u81ea\u5df1\u7684\u8bdd\u628a\u6545\u4e8b\u590d\u8ff0\u4e00\u904d\u518d\u53bb\u6838\u5bf9\u2014\u2014\u81ea\u6211\u6d4b\u8bd5\u9501\u4f4f\u7684\u4e1c\u897f\uff0c\u8fdc\u591a\u4e8e\u53cd\u590d\u91cd\u8bfb\u3002",faq:[["\u8fd9\u548c\u533b\u751f\u7528\u7684\u903b\u8f91\u8bb0\u5fc6\u6d4b\u9a8c\u662f\u4e00\u56de\u4e8b\u5417\uff1f","\u5b83\u7528\u7684\u662f\u540c\u6837\u7684\u5f62\u5f0f\u2014\u2014\u7acb\u523b\u3001\u4ee5\u53ca\u5ef6\u8fdf\u4e4b\u540e\u590d\u8ff0\u4e00\u4e2a\u77ed\u7bc7\u6545\u4e8b\u2014\u2014\u4f46\u4f5c\u4e3a\u65e5\u5e38\u7ec3\u4e60\uff0c\u800c\u975e\u4e34\u5e8a\u8bc4\u4f30\u3002\u6d4b\u9a8c\u7248\u672c\u662f\u6807\u51c6\u5316\u7684\u3001\u7531\u4e13\u4e1a\u4eba\u5458\u8bc4\u5206\uff1b\u8bad\u7ec3\u5668\u53ea\u662f\u8ba9\u4f60\u953b\u70bc\u540c\u6837\u7684\u6280\u80fd\u3002"],["\u5b83\u4f1a\u5168\u9762\u6539\u5584\u6211\u7684\u8bb0\u5fc6\u5417\uff1f","\u5b83\u4f1a\u53ef\u9760\u5730\u8ba9\u4f60\u66f4\u64c5\u957f\u8bb0\u6545\u4e8b\u548c\u7c7b\u4f3c\u6750\u6599\u3002\u81f3\u4e8e\u5e7f\u6cdb\u63d0\u5347\u65e0\u5173\u7684\u65e5\u5e38\u8bb0\u5fc6\uff0c\u8bc1\u636e\u652f\u6301\u5f97\u5e76\u4e0d\u5145\u5206\uff0c\u6240\u4ee5\u9884\u671f\u6536\u76ca\u4f1a\u8d34\u8fd1\u4f60\u5b9e\u9645\u7ec3\u4e60\u7684\u5185\u5bb9\u3002"],["\u6211\u8be5\u628a\u539f\u8bdd\u4e00\u5b57\u4e0d\u5dee\u5730\u80cc\u4e0b\u6765\u5417\uff1f","\u4e0d\u7528\u3002\u7784\u51c6\u542b\u4e49\u548c\u5177\u4f53\u7ec6\u8282\u2014\u2014\u53d1\u751f\u4e86\u4ec0\u4e48\u3001\u5bf9\u8c01\u53d1\u751f\u3001\u4eba\u540d\u548c\u6570\u5b57\u3002\u9010\u9879\u7ec6\u8282\u8bc4\u5206\u5956\u52b1\u7684\u662f\u51c6\u786e\u7684\u5185\u5bb9\uff0c\u800c\u57fa\u4e8e\u542b\u4e49\u7684\u56de\u5fc6\u6bd4\u9010\u5b57\u786c\u80cc\u8981\u625b\u5f97\u4f4f\u5f97\u591a\u3002"]],variants:"\u53ef\u4ee5\u901a\u8fc7\u6545\u4e8b\u957f\u5ea6\uff0c\u4ee5\u53ca\u4eba\u540d\u3001\u6570\u5b57\u3001\u65e5\u671f\u7684\u5bc6\u5ea6\u6765\u8c03\u8282\u8d1f\u8377\u3002\u5728\u9605\u8bfb\u548c\u8046\u542c\u4e4b\u95f4\u5207\u6362\uff0c\u5728\u5373\u65f6\u4e0e\u5ef6\u8fdf\uff0820\u201330 \u5206\u949f\uff09\u56de\u5fc6\u4e4b\u95f4\u5207\u6362\uff0c\u5728\u81ea\u7531\u590d\u8ff0\u4e0e\u56de\u7b54\u5173\u4e8e\u8be5\u6587\u6bb5\u7684\u5177\u4f53\u95ee\u9898\u4e4b\u95f4\u5207\u6362\uff1b\u4e25\u683c\u6309\u987a\u5e8f\u56de\u5fc6\u4e8b\u4ef6\u53c8\u662f\u4e00\u79cd\u66f4\u96be\u7684\u6a21\u5f0f\u3002"}},stroop:{ru:{about:"\u0421\u043b\u043e\u0432\u0430-\u043d\u0430\u0437\u0432\u0430\u043d\u0438\u044f \u0446\u0432\u0435\u0442\u043e\u0432 \u043d\u0430\u043f\u0435\u0447\u0430\u0442\u0430\u043d\u044b \u043d\u0435\u0441\u043e\u0432\u043f\u0430\u0434\u0430\u044e\u0449\u0435\u0439 \u043a\u0440\u0430\u0441\u043a\u043e\u0439 \u2014 \u0441\u043b\u043e\u0432\u043e \xab\u041a\u0420\u0410\u0421\u041d\u042b\u0419\xbb \u0441\u0438\u043d\u0438\u043c \u2014 \u0438 \u043d\u0443\u0436\u043d\u043e \u043d\u0430\u0437\u0432\u0430\u0442\u044c \u0446\u0432\u0435\u0442 \u043a\u0440\u0430\u0441\u043a\u0438, \u0430 \u043d\u0435 \u043f\u0440\u043e\u0447\u0438\u0442\u0430\u0442\u044c \u0441\u043b\u043e\u0432\u043e. \u041d\u0430\u0437\u0432\u0430\u0442\u044c \u0446\u0432\u0435\u0442 = \u043f\u043e\u0434\u0430\u0432\u0438\u0442\u044c \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u043e\u0435 \u0436\u0435\u043b\u0430\u043d\u0438\u0435 \u043f\u0440\u043e\u0447\u0438\u0442\u0430\u0442\u044c.",benefit:"\u0422\u043e\u0440\u043c\u043e\u0437\u043d\u044b\u0439 \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044c \u2014 \u043f\u043e\u0434\u0430\u0432\u043b\u0435\u043d\u0438\u0435 \u0431\u044b\u0441\u0442\u0440\u043e\u0439 \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u043e\u0439 \u0440\u0435\u0430\u043a\u0446\u0438\u0438 \u0432 \u043f\u043e\u043b\u044c\u0437\u0443 \u043c\u0435\u0434\u043b\u0435\u043d\u043d\u043e\u0439, \u043d\u043e \u043d\u0443\u0436\u043d\u043e\u0439 \u2014 \u043f\u043b\u044e\u0441 \u0438\u0437\u0431\u0438\u0440\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0435 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u0438 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u043e\u0431\u0440\u0430\u0431\u043e\u0442\u043a\u0438.",history:"\u041e\u0434\u0438\u043d \u0438\u0437 \u0441\u0430\u043c\u044b\u0445 \u0446\u0438\u0442\u0438\u0440\u0443\u0435\u043c\u044b\u0445 \u044d\u043a\u0441\u043f\u0435\u0440\u0438\u043c\u0435\u043d\u0442\u043e\u0432 \u0432 \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u0438; \u0441 1930-\u0445 \u0430\u0434\u0430\u043f\u0442\u0438\u0440\u043e\u0432\u0430\u043d \u0442\u044b\u0441\u044f\u0447\u0438 \u0440\u0430\u0437 \u0438 \u0441\u043b\u0443\u0436\u0438\u0442 \u0441\u0442\u0430\u043d\u0434\u0430\u0440\u0442\u043d\u043e\u0439 \u043a\u043b\u0438\u043d\u0438\u0447\u0435\u0441\u043a\u043e\u0439 \u0438 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u044c\u0441\u043a\u043e\u0439 \u043c\u0435\u0440\u043e\u0439 \u0443\u043f\u0440\u0430\u0432\u043b\u044f\u044e\u0449\u0438\u0445 \u0444\u0443\u043d\u043a\u0446\u0438\u0439.",creator:"\u0414\u0436\u043e\u043d \u0420\u0438\u0434\u043b\u0438 \u0421\u0442\u0440\u0443\u043f \u2014 \u043e\u043f\u0438\u0441\u0430\u043b \u044d\u0444\u0444\u0435\u043a\u0442 \u0432 \u0441\u0442\u0430\u0442\u044c\u0435 1935 \u0433\u043e\u0434\u0430 \xabStudies of Interference in Serial Verbal Reactions\xbb.",methods:"\u0421\u043d\u0430\u0447\u0430\u043b\u0430 \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u044c, \u043f\u043e\u0442\u043e\u043c \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c. \u0421\u043b\u0435\u0434\u0438 \u0437\u0430 \xab\u0446\u0435\u043d\u043e\u0439 \u043f\u043e\u043c\u0435\u0445\u0438\xbb \u2014 \u043b\u0438\u0448\u043d\u0438\u043c \u0432\u0440\u0435\u043c\u0435\u043d\u0435\u043c \u043d\u0430 \u043d\u0435\u0441\u043e\u0432\u043f\u0430\u0434\u0430\u044e\u0449\u0438\u0445 \u043f\u0440\u043e\u0431\u0430\u0445 \u043f\u0440\u043e\u0442\u0438\u0432 \u0441\u043e\u0432\u043f\u0430\u0434\u0430\u044e\u0449\u0438\u0445, \u2014 \u0430 \u043d\u0435 \u0437\u0430 \u0447\u0438\u0441\u0442\u044b\u043c \u0432\u0440\u0435\u043c\u0435\u043d\u0435\u043c \u0440\u0435\u0430\u043a\u0446\u0438\u0438. \u0414\u0435\u0440\u0436\u0438 \u0431\u043b\u043e\u043a\u0438 \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u043c\u0438, \u0447\u0442\u043e\u0431\u044b \u0443\u0441\u0442\u0430\u043b\u043e\u0441\u0442\u044c \u043d\u0435 \u0440\u0430\u0437\u0434\u0443\u0432\u0430\u043b\u0430 \u043e\u0448\u0438\u0431\u043a\u0438.",duration:"\u041d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u043c\u0438\u043d\u0443\u0442 \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u043c\u0438 \u0431\u043b\u043e\u043a\u0430\u043c\u0438, \u043f\u0430\u0440\u0443-\u0442\u0440\u043e\u0439\u043a\u0443 \u0440\u0430\u0437 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e. \u0426\u0435\u043d\u0430 \u043f\u043e\u043c\u0435\u0445\u0438 \u043e\u0431\u044b\u0447\u043d\u043e \u043f\u0430\u0434\u0430\u0435\u0442 \u0437\u0430 \u043f\u0435\u0440\u0432\u044b\u0435 \u0441\u0435\u0441\u0441\u0438\u0438, \u043a\u043e\u0433\u0434\u0430 \u043f\u043e\u0434\u0430\u0432\u043b\u0435\u043d\u0438\u0435 \u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u0441\u044f \u044d\u0444\u0444\u0435\u043a\u0442\u0438\u0432\u043d\u0435\u0435, \u043f\u043e\u0442\u043e\u043c \u0432\u044b\u0445\u043e\u0434\u0438\u0442 \u043d\u0430 \u043f\u043b\u0430\u0442\u043e.",research:"\u0421\u0430\u043c \u044d\u0444\u0444\u0435\u043a\u0442 \u0436\u0435\u043b\u0435\u0437\u043e\u0431\u0435\u0442\u043e\u043d\u043d\u044b\u0439 \u0438 \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0438\u0442\u0441\u044f \u043f\u043e\u0447\u0442\u0438 \u0443 \u0432\u0441\u0435\u0445. \u0422\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0430 \u043d\u0430\u0434\u0451\u0436\u043d\u043e \u0441\u043d\u0438\u0436\u0430\u0435\u0442 \u0442\u0432\u043e\u044e \u0446\u0435\u043d\u0443 \u043f\u043e\u043c\u0435\u0445\u0438 \u0432 \u0437\u0430\u0434\u0430\u0447\u0435; \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0438\u0442\u0441\u044f \u043b\u0438 \u044d\u0442\u043e \u043d\u0430 \u0431\u044b\u0442\u043e\u0432\u043e\u0439 \u0441\u0430\u043c\u043e\u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044c \u2014 \u043a\u0443\u0434\u0430 \u043c\u0435\u043d\u0435\u0435 \u044f\u0441\u043d\u043e, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0439 \u0440\u0430\u0434\u0438 \u043a\u043e\u043d\u043a\u0440\u0435\u0442\u043d\u043e\u0433\u043e \u043d\u0430\u0432\u044b\u043a\u0430, \u0430 \u043d\u0435 \xab\u043f\u0440\u043e\u043a\u0430\u0447\u043a\u0438 \u0441\u0438\u043b\u044b \u0432\u043e\u043b\u0438\xbb.",rec:"\u0418\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0439, \u0447\u0442\u043e\u0431\u044b \u043e\u0442\u0442\u0430\u0447\u0438\u0432\u0430\u0442\u044c \u0442\u043e\u0447\u043d\u043e\u0435 \u0431\u044b\u0441\u0442\u0440\u043e\u0435 \u043f\u043e\u0434\u0430\u0432\u043b\u0435\u043d\u0438\u0435 \u0432 \u043a\u043e\u043d\u0444\u043b\u0438\u043a\u0442\u0435. \u041e\u0441\u0442\u0430\u043d\u0430\u0432\u043b\u0438\u0432\u0430\u0439\u0441\u044f, \u043a\u0430\u043a \u0442\u043e\u043b\u044c\u043a\u043e \u0440\u0430\u0441\u0442\u0443\u0442 \u043e\u0448\u0438\u0431\u043a\u0438 \u2014 \u043d\u0435\u0440\u044f\u0448\u043b\u0438\u0432\u0430\u044f \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u044d\u0442\u043e \u043d\u0435 \u043d\u0430\u0432\u044b\u043a.",faq:[["\u0427\u0442\u043e \u0442\u0430\u043a\u043e\u0435 \u044d\u0444\u0444\u0435\u043a\u0442 \u0421\u0442\u0440\u0443\u043f\u0430?","\u0417\u0430\u043c\u0435\u0434\u043b\u0435\u043d\u0438\u0435, \u043a\u043e\u0433\u0434\u0430 \u043d\u0430\u0437\u044b\u0432\u0430\u0435\u0448\u044c \u0446\u0432\u0435\u0442 \u043a\u0440\u0430\u0441\u043a\u0438 \u0443 \u0441\u043b\u043e\u0432\u0430, \u043a\u043e\u0442\u043e\u0440\u043e\u0435 \u043e\u0437\u043d\u0430\u0447\u0430\u0435\u0442 \u0434\u0440\u0443\u0433\u043e\u0439 \u0446\u0432\u0435\u0442 \u2014 \u0447\u0442\u0435\u043d\u0438\u0435 \u043c\u0435\u0448\u0430\u0435\u0442 \u043d\u0430\u0437\u044b\u0432\u0430\u043d\u0438\u044e."],["\u0427\u0442\u043e \u0438\u0437\u043c\u0435\u0440\u044f\u0435\u0442?","\u0422\u043e\u0440\u043c\u043e\u0437\u043d\u044b\u0439 \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044c \u0438 \u0438\u0437\u0431\u0438\u0440\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0435 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u2014 \u044f\u0434\u0440\u043e \u0443\u043f\u0440\u0430\u0432\u043b\u044f\u044e\u0449\u0438\u0445 \u0444\u0443\u043d\u043a\u0446\u0438\u0439."],["\u041c\u043e\u0436\u043d\u043e \u043b\u0438 \u043d\u0430\u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u0430\u0442\u044c?","\u0421\u0432\u043e\u044e \u0446\u0435\u043d\u0443 \u043f\u043e\u043c\u0435\u0445\u0438 \u0432 \u0437\u0430\u0434\u0430\u0447\u0435 \u0441\u043d\u0438\u0437\u0438\u0442\u044c \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u043e\u0439 \u043c\u043e\u0436\u043d\u043e; \u0448\u0438\u0440\u043e\u043a\u0438\u0439 \u043f\u0435\u0440\u0435\u043d\u043e\u0441 \u043d\u0430 \u0441\u0430\u043c\u043e\u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044c \u0432 \u0436\u0438\u0437\u043d\u0438 \u0434\u043e\u043a\u0430\u0437\u0430\u043d \u0441\u043b\u0430\u0431\u043e."]],variants:"\u041a\u043b\u0430\u0441\u0441\u0438\u0447\u0435\u0441\u043a\u0438\u0439 \u0446\u0432\u0435\u0442-\u0441\u043b\u043e\u0432\u043e; \u044d\u043c\u043e\u0446\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u044b\u0439 \u0421\u0442\u0440\u0443\u043f (\u044d\u043c\u043e\u0446\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u044b\u0435 \u0441\u043b\u043e\u0432\u0430 \u0432\u043c\u0435\u0441\u0442\u043e \u0446\u0432\u0435\u0442\u043e\u0432); \u0447\u0438\u0441\u043b\u043e\u0432\u043e\u0439 \u0438 \u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0439 \u0421\u0442\u0440\u0443\u043f; \u043e\u0431\u0440\u0430\u0442\u043d\u044b\u0435 \u0432\u0435\u0440\u0441\u0438\u0438, \u0433\u0434\u0435 \u0447\u0438\u0442\u0430\u0435\u0448\u044c \u0441\u043b\u043e\u0432\u043e \u0438 \u0438\u0433\u043d\u043e\u0440\u0438\u0448\u044c \u043a\u0440\u0430\u0441\u043a\u0443."},en:{about:"Words for colours are printed in a mismatched ink \u2014 the word \"RED\" in blue \u2014 and you must name the ink, not read the word. Naming the colour means overriding the automatic urge to read.",benefit:"Inhibitory control \u2014 suppressing a fast, automatic response in favour of a slower, goal-relevant one \u2014 plus selective attention and processing speed.",history:"One of psychology's most-cited experiments. It has been adapted thousands of times since the 1930s and is a standard clinical and research measure of executive function.",creator:"John Ridley Stroop, who described the effect in his 1935 paper \"Studies of Interference in Serial Verbal Reactions\".",methods:"Go for accuracy first, then speed. Track your interference cost \u2014 the extra time on mismatched (incongruent) trials versus matched ones \u2014 rather than raw reaction time. Keep blocks short so fatigue does not inflate errors.",duration:"A few minutes of short blocks, a handful of times a week. Your interference cost typically shrinks over the first sessions as the override becomes more efficient, then levels off.",research:"The effect itself is rock-solid and reproduces in almost everyone. Training reliably shrinks your own interference on the task; whether that carries over to everyday self-control is far less certain, so train it for the specific skill, not a broad willpower upgrade.",rec:"Use it to sharpen accurate, fast overriding under conflict. Stop the moment errors climb \u2014 sloppy speed is not the skill.",faq:[["What is the Stroop effect?","The slowdown when you name the ink colour of a colour word that spells a different colour \u2014 reading interferes with naming."],["What does it measure?","Inhibitory control and selective attention, a core part of executive function."],["Can I train it?","You can lower your own interference cost with practice; broad transfer to real-life self-control is not well established."]],variants:"Classic colour-word; emotional Stroop (emotional words instead of colours); numerical and spatial Stroop; and reverse versions where you read the word and ignore the ink."},es:{about:"Las palabras que designan colores est\xe1n impresas en una tinta que no concuerda \u2014la palabra \"ROJO\" en azul\u2014 y debes nombrar la tinta, no leer la palabra. Nombrar el color implica anular el impulso autom\xe1tico de leer.",benefit:"Control inhibitorio \u2014suprimir una respuesta r\xe1pida y autom\xe1tica en favor de otra m\xe1s lenta y acorde al objetivo\u2014 m\xe1s atenci\xf3n selectiva y velocidad de procesamiento.",history:"Uno de los experimentos m\xe1s citados de la psicolog\xeda. Se ha adaptado miles de veces desde la d\xe9cada de 1930 y es una medida cl\xednica y de investigaci\xf3n est\xe1ndar de la funci\xf3n ejecutiva.",creator:"John Ridley Stroop, que describi\xf3 el efecto en su art\xedculo de 1935 \"Studies of Interference in Serial Verbal Reactions\".",methods:"Busca primero la precisi\xf3n, luego la velocidad. Lleva la cuenta de tu coste de interferencia \u2014el tiempo extra en los ensayos no concordantes (incongruentes) frente a los concordantes\u2014 en lugar del tiempo de reacci\xf3n puro. Mant\xe9n los bloques cortos para que el cansancio no infle los errores.",duration:"Unos pocos minutos en bloques cortos, un pu\xf1ado de veces por semana. Tu coste de interferencia suele reducirse durante las primeras sesiones a medida que la anulaci\xf3n se vuelve m\xe1s eficiente, y luego se estabiliza.",research:"El efecto en s\xed es rocosamente s\xf3lido y se reproduce en casi todo el mundo. El entrenamiento reduce de forma fiable tu propia interferencia en la tarea; que eso se traslade al autocontrol cotidiano es mucho menos seguro, as\xed que entr\xe9nalo por la habilidad espec\xedfica, no por una mejora amplia de la fuerza de voluntad.",rec:"\xdasalo para afilar una anulaci\xf3n precisa y r\xe1pida bajo conflicto. Detente en cuanto suban los errores: la velocidad descuidada no es la habilidad.",faq:[["\xbfQu\xe9 es el efecto Stroop?","La ralentizaci\xf3n al nombrar el color de la tinta de una palabra de color que deletrea un color distinto: la lectura interfiere con la denominaci\xf3n."],["\xbfQu\xe9 mide?","El control inhibitorio y la atenci\xf3n selectiva, una parte central de la funci\xf3n ejecutiva."],["\xbfPuedo entrenarlo?","Puedes reducir tu propio coste de interferencia con la pr\xe1ctica; la transferencia amplia al autocontrol de la vida real no est\xe1 bien establecida."]],variants:"El cl\xe1sico de palabra-color; el Stroop emocional (palabras emocionales en lugar de colores); el Stroop num\xe9rico y espacial; y las versiones inversas donde lees la palabra e ignoras la tinta."},de:{about:"Farbw\xf6rter werden in einer nicht passenden Tinte gedruckt \u2014 das Wort \"ROT\" in Blau \u2014 und du musst die Tinte benennen, nicht das Wort lesen. Die Farbe zu benennen hei\xdft, den automatischen Drang zu lesen zu \xfcberschreiben.",benefit:"Inhibitorische Kontrolle \u2014 das Unterdr\xfccken einer schnellen, automatischen Reaktion zugunsten einer langsameren, zielrelevanten \u2014 sowie selektive Aufmerksamkeit und Verarbeitungsgeschwindigkeit.",history:"Eines der meistzitierten Experimente der Psychologie. Es wurde seit den 1930er-Jahren tausendfach abgewandelt und ist ein klinisches und wissenschaftliches Standardma\xdf f\xfcr exekutive Funktionen.",creator:"John Ridley Stroop, der den Effekt in seinem Aufsatz von 1935 \"Studies of Interference in Serial Verbal Reactions\" beschrieb.",methods:"Ziele zuerst auf Genauigkeit, dann auf Tempo. Verfolge deine Interferenzkosten \u2014 die zus\xe4tzliche Zeit bei nicht passenden (inkongruenten) Durchg\xe4ngen gegen\xfcber passenden \u2014 statt der rohen Reaktionszeit. Halte die Bl\xf6cke kurz, damit M\xfcdigkeit die Fehler nicht aufbl\xe4ht.",duration:"Ein paar Minuten kurze Bl\xf6cke, eine Handvoll Mal pro Woche. Deine Interferenzkosten schrumpfen \xfcblicherweise \xfcber die ersten Einheiten, w\xe4hrend das \xdcberschreiben effizienter wird, und pendeln sich dann ein.",research:"Der Effekt selbst ist bombenfest und reproduziert sich bei nahezu jedem. Training verkleinert zuverl\xe4ssig deine eigene Interferenz bei der Aufgabe; ob sich das auf die allt\xe4gliche Selbstkontrolle \xfcbertr\xe4gt, ist weit weniger sicher, also trainiere es f\xfcr die spezifische F\xe4higkeit, nicht f\xfcr ein breites Willenskraft-Upgrade.",rec:"Nutze es, um das genaue, schnelle \xdcberschreiben unter Konflikt zu sch\xe4rfen. H\xf6r in dem Moment auf, in dem die Fehler steigen \u2014 schludriges Tempo ist nicht die F\xe4higkeit.",faq:[["Was ist der Stroop-Effekt?","Die Verlangsamung, wenn du die Tintenfarbe eines Farbworts benennst, das eine andere Farbe buchstabiert \u2014 das Lesen st\xf6rt das Benennen."],["Was misst er?","Inhibitorische Kontrolle und selektive Aufmerksamkeit, ein Kernbestandteil der exekutiven Funktionen."],["Kann ich ihn trainieren?","Du kannst deine eigenen Interferenzkosten mit \xdcbung senken; ein breiter Transfer auf die Selbstkontrolle im echten Leben ist nicht gut belegt."]],variants:"Klassischer Farbwort-Stroop; emotionaler Stroop (emotionale W\xf6rter statt Farben); numerischer und r\xe4umlicher Stroop; sowie umgekehrte Versionen, bei denen du das Wort liest und die Tinte ignorierst."},pt:{about:"Palavras de cor s\xe3o impressas numa tinta que n\xe3o combina \u2014 a palavra \"VERMELHO\" em azul \u2014 e voc\xea precisa nomear a tinta, n\xe3o ler a palavra. Nomear a cor significa anular o impulso autom\xe1tico de ler.",benefit:"Controle inibit\xf3rio \u2014 suprimir uma resposta r\xe1pida e autom\xe1tica em favor de outra mais lenta e relevante ao objetivo \u2014 al\xe9m de aten\xe7\xe3o seletiva e velocidade de processamento.",history:"Um dos experimentos mais citados da psicologia. Foi adaptado milhares de vezes desde os anos 1930 e \xe9 uma medida cl\xednica e de pesquisa padr\xe3o da fun\xe7\xe3o executiva.",creator:"John Ridley Stroop, que descreveu o efeito em seu artigo de 1935 \"Studies of Interference in Serial Verbal Reactions\".",methods:"Busque a precis\xe3o primeiro, depois a velocidade. Acompanhe seu custo de interfer\xeancia \u2014 o tempo extra nas tentativas que n\xe3o combinam (incongruentes) em rela\xe7\xe3o \xe0s que combinam \u2014 e n\xe3o o tempo de rea\xe7\xe3o puro. Mantenha os blocos curtos para que o cansa\xe7o n\xe3o infle os erros.",duration:"Alguns minutos de blocos curtos, um punhado de vezes por semana. Seu custo de interfer\xeancia costuma encolher nas primeiras sess\xf5es, \xe0 medida que a anula\xe7\xe3o fica mais eficiente, e depois se estabiliza.",research:"O efeito em si \xe9 firm\xedssimo e se reproduz em quase todo mundo. O treino reduz de forma confi\xe1vel a sua pr\xf3pria interfer\xeancia na tarefa; se isso se transfere para o autocontrole do dia a dia \xe9 bem menos certo, ent\xe3o treine-o pela habilidade espec\xedfica, n\xe3o por uma melhoria ampla de for\xe7a de vontade.",rec:"Use-o para afiar a anula\xe7\xe3o precisa e r\xe1pida sob conflito. Pare assim que os erros subirem \u2014 velocidade desleixada n\xe3o \xe9 a habilidade.",faq:[["O que \xe9 o efeito Stroop?","A lentid\xe3o ao nomear a cor da tinta de uma palavra de cor que soletra uma cor diferente \u2014 a leitura interfere na nomea\xe7\xe3o."],["O que ele mede?","Controle inibit\xf3rio e aten\xe7\xe3o seletiva, uma parte central da fun\xe7\xe3o executiva."],["D\xe1 para trein\xe1-lo?","Voc\xea consegue reduzir seu pr\xf3prio custo de interfer\xeancia com a pr\xe1tica; uma transfer\xeancia ampla para o autocontrole da vida real n\xe3o est\xe1 bem estabelecida."]],variants:"O cl\xe1ssico palavra-cor; o Stroop emocional (palavras emocionais em vez de cores); o Stroop num\xe9rico e o espacial; e vers\xf5es reversas em que voc\xea l\xea a palavra e ignora a tinta."},hi:{about:"\u0930\u0902\u0917\u094b\u0902 \u0915\u0947 \u0928\u093e\u092e \u0915\u093f\u0938\u0940 \u092c\u0947\u092e\u0947\u0932 \u0938\u094d\u092f\u093e\u0939\u0940 \u092e\u0947\u0902 \u091b\u092a\u0947 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902 \u2014 \"\u0932\u093e\u0932\" \u0936\u092c\u094d\u0926 \u0928\u0940\u0932\u0940 \u0938\u094d\u092f\u093e\u0939\u0940 \u092e\u0947\u0902 \u2014 \u0914\u0930 \u0906\u092a\u0915\u094b \u0938\u094d\u092f\u093e\u0939\u0940 \u0915\u093e \u0930\u0902\u0917 \u092c\u0924\u093e\u0928\u093e \u0939\u0948, \u0936\u092c\u094d\u0926 \u0928\u0939\u0940\u0902 \u092a\u0922\u093c\u0928\u093e \u0939\u0948\u0964 \u0930\u0902\u0917 \u0915\u093e \u0928\u093e\u092e \u092c\u0924\u093e\u0928\u0947 \u0915\u093e \u092e\u0924\u0932\u092c \u0939\u0948 \u092a\u0922\u093c\u0928\u0947 \u0915\u0940 \u0938\u094d\u0935\u0924\u0903\u091a\u093e\u0932\u093f\u0924 \u0932\u0932\u0915 \u0915\u094b \u0926\u092c\u093e \u0926\u0947\u0928\u093e\u0964",benefit:"\u0905\u0935\u0930\u094b\u0927\u0915 \u0928\u093f\u092f\u0902\u0924\u094d\u0930\u0923 \u2014 \u0915\u093f\u0938\u0940 \u0924\u0947\u091c\u093c, \u0938\u094d\u0935\u0924\u0903\u091a\u093e\u0932\u093f\u0924 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0915\u094b \u0926\u092c\u093e\u0915\u0930 \u0909\u0938\u0915\u0940 \u091c\u0917\u0939 \u0915\u093f\u0938\u0940 \u0927\u0940\u092e\u0940, \u0932\u0915\u094d\u0937\u094d\u092f-\u092a\u094d\u0930\u093e\u0938\u0902\u0917\u093f\u0915 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0915\u094b \u091a\u0941\u0928\u0928\u093e \u2014 \u0938\u093e\u0925 \u0939\u0940 \u091a\u092f\u0928\u093e\u0924\u094d\u092e\u0915 \u0927\u094d\u092f\u093e\u0928 \u0914\u0930 \u092a\u094d\u0930\u0938\u0902\u0938\u094d\u0915\u0930\u0923-\u0917\u0924\u093f\u0964",history:"\u092e\u0928\u094b\u0935\u093f\u091c\u094d\u091e\u093e\u0928 \u0915\u0947 \u0938\u092c\u0938\u0947 \u0905\u0927\u093f\u0915 \u0909\u0926\u094d\u0927\u0943\u0924 \u092a\u094d\u0930\u092f\u094b\u0917\u094b\u0902 \u092e\u0947\u0902 \u0938\u0947 \u090f\u0915\u0964 1930 \u0915\u0947 \u0926\u0936\u0915 \u0938\u0947 \u0907\u0938\u0947 \u0939\u091c\u093c\u093e\u0930\u094b\u0902 \u092c\u093e\u0930 \u0922\u093e\u0932\u093e \u091c\u093e \u091a\u0941\u0915\u093e \u0939\u0948 \u0914\u0930 \u092f\u0939 \u0915\u093e\u0930\u094d\u092f\u0915\u093e\u0930\u0940 \u0915\u093e\u0930\u094d\u092f \u0915\u093e \u090f\u0915 \u092e\u093e\u0928\u0915 \u0928\u0948\u0926\u093e\u0928\u093f\u0915 \u0924\u0925\u093e \u0936\u094b\u0927 \u092e\u093e\u092a \u0939\u0948\u0964",creator:"John Ridley Stroop, \u091c\u093f\u0928\u094d\u0939\u094b\u0902\u0928\u0947 \u0905\u092a\u0928\u0947 1935 \u0915\u0947 \u0936\u094b\u0927-\u092a\u0924\u094d\u0930 \"Studies of Interference in Serial Verbal Reactions\" \u092e\u0947\u0902 \u0907\u0938 \u092a\u094d\u0930\u092d\u093e\u0935 \u0915\u093e \u0935\u0930\u094d\u0923\u0928 \u0915\u093f\u092f\u093e\u0964",methods:"\u092a\u0939\u0932\u0947 \u0938\u091f\u0940\u0915\u0924\u093e \u092a\u0930 \u091c\u093e\u090f\u0901, \u092b\u093f\u0930 \u0930\u092b\u093c\u094d\u0924\u093e\u0930 \u092a\u0930\u0964 \u0915\u094b\u0930\u0947 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0938\u092e\u092f \u0915\u0947 \u092c\u091c\u093e\u092f \u0905\u092a\u0928\u0940 \u0935\u094d\u092f\u0924\u093f\u0915\u0930\u0923-\u0915\u0940\u092e\u0924 \u092a\u0930 \u0928\u091c\u093c\u0930 \u0930\u0916\u0947\u0902 \u2014 \u092f\u093e\u0928\u0940 \u092c\u0947\u092e\u0947\u0932 (\u0905\u0938\u0902\u0917\u0924) \u092a\u094d\u0930\u092f\u093e\u0938\u094b\u0902 \u092e\u0947\u0902 \u092e\u0947\u0932 \u0916\u093e\u0928\u0947 \u0935\u093e\u0932\u0947 \u092a\u094d\u0930\u092f\u093e\u0938\u094b\u0902 \u0915\u0947 \u092e\u0941\u0915\u093e\u092c\u0932\u0947 \u0932\u0917\u0928\u0947 \u0935\u093e\u0932\u093e \u0905\u0924\u093f\u0930\u093f\u0915\u094d\u0924 \u0938\u092e\u092f\u0964 \u092c\u094d\u0932\u0949\u0915 \u091b\u094b\u091f\u0947 \u0930\u0916\u0947\u0902 \u0924\u093e\u0915\u093f \u0925\u0915\u093e\u0928 \u0917\u0932\u0924\u093f\u092f\u093e\u0901 \u0928 \u092c\u0922\u093c\u093e \u0926\u0947\u0964",duration:"\u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u0915\u0941\u091b \u092c\u093e\u0930, \u091b\u094b\u091f\u0947 \u092c\u094d\u0932\u0949\u0915\u094b\u0902 \u0915\u0947 \u0915\u0941\u091b \u092e\u093f\u0928\u091f\u0964 \u0906\u092a\u0915\u0940 \u0935\u094d\u092f\u0924\u093f\u0915\u0930\u0923-\u0915\u0940\u092e\u0924 \u0906\u092e\u0924\u094c\u0930 \u092a\u0930 \u092a\u0939\u0932\u0947 \u0915\u0941\u091b \u0938\u0924\u094d\u0930\u094b\u0902 \u092e\u0947\u0902 \u0918\u091f\u0924\u0940 \u0939\u0948 \u091c\u0948\u0938\u0947-\u091c\u0948\u0938\u0947 \u092f\u0939 \u0926\u092c\u093e\u0935-\u0915\u094d\u0930\u093f\u092f\u093e \u0905\u0927\u093f\u0915 \u0915\u0941\u0936\u0932 \u0939\u094b\u0924\u0940 \u091c\u093e\u0924\u0940 \u0939\u0948, \u092b\u093f\u0930 \u0925\u092e \u091c\u093e\u0924\u0940 \u0939\u0948\u0964",research:"\u092a\u094d\u0930\u092d\u093e\u0935 \u0905\u092a\u0928\u0947 \u0906\u092a \u092e\u0947\u0902 \u092c\u0947\u0939\u0926 \u092a\u0941\u0916\u094d\u0924\u093e \u0939\u0948 \u0914\u0930 \u0932\u0917\u092d\u0917 \u0939\u0930 \u0915\u093f\u0938\u0940 \u092e\u0947\u0902 \u0926\u094b\u0939\u0930\u093e\u092f\u093e \u091c\u093e\u0924\u093e \u0939\u0948\u0964 \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0922\u0902\u0917 \u0938\u0947 \u0907\u0938 \u0915\u093e\u0930\u094d\u092f \u092a\u0930 \u0906\u092a\u0915\u0940 \u0905\u092a\u0928\u0940 \u0935\u094d\u092f\u0924\u093f\u0915\u0930\u0923-\u0915\u0940\u092e\u0924 \u0918\u091f\u093e\u0924\u093e \u0939\u0948; \u092a\u0930 \u092f\u0939 \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0947 \u0906\u0924\u094d\u092e-\u0928\u093f\u092f\u0902\u0924\u094d\u0930\u0923 \u0924\u0915 \u092a\u0939\u0941\u0901\u091a\u0924\u093e \u0939\u0948 \u092f\u093e \u0928\u0939\u0940\u0902, \u092f\u0939 \u0915\u0939\u0940\u0902 \u0915\u092e \u0924\u092f \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0907\u0938\u0947 \u0915\u093f\u0938\u0940 \u0935\u094d\u092f\u093e\u092a\u0915 \u0907\u091a\u094d\u091b\u093e\u0936\u0915\u094d\u0924\u093f-\u0909\u0928\u094d\u0928\u0924\u093f \u0915\u0947 \u0932\u093f\u090f \u0928\u0939\u0940\u0902, \u092c\u0932\u094d\u0915\u093f \u0907\u0938 \u0916\u093c\u093e\u0938 \u0915\u094c\u0936\u0932 \u0915\u0947 \u0932\u093f\u090f \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u093f\u0924 \u0915\u0930\u0947\u0902\u0964",rec:"\u0907\u0938\u0915\u093e \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0926\u094d\u0935\u0902\u0926\u094d\u0935 \u0915\u0940 \u0938\u094d\u0925\u093f\u0924\u093f \u092e\u0947\u0902 \u0938\u091f\u0940\u0915, \u0924\u0947\u091c\u093c \u0926\u092c\u093e\u0935-\u0915\u094d\u0930\u093f\u092f\u093e \u0915\u0940 \u0927\u093e\u0930 \u0924\u0947\u091c\u093c \u0915\u0930\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0915\u0930\u0947\u0902\u0964 \u091c\u0948\u0938\u0947 \u0939\u0940 \u0917\u0932\u0924\u093f\u092f\u093e\u0901 \u092c\u0922\u093c\u0947\u0902, \u0924\u0941\u0930\u0902\u0924 \u0930\u0941\u0915 \u091c\u093e\u090f\u0901 \u2014 \u0932\u093e\u092a\u0930\u0935\u093e\u0939 \u0930\u092b\u093c\u094d\u0924\u093e\u0930 \u0935\u0939 \u0915\u094c\u0936\u0932 \u0928\u0939\u0940\u0902 \u0939\u0948\u0964",faq:[["Stroop \u092a\u094d\u0930\u092d\u093e\u0935 \u0915\u094d\u092f\u093e \u0939\u0948?","\u0935\u0939 \u0938\u0941\u0938\u094d\u0924\u0940 \u091c\u094b \u0924\u092c \u0906\u0924\u0940 \u0939\u0948 \u091c\u092c \u0906\u092a \u0915\u093f\u0938\u0940 \u0910\u0938\u0947 \u0930\u0902\u0917-\u0936\u092c\u094d\u0926 \u0915\u0940 \u0938\u094d\u092f\u093e\u0939\u0940 \u0915\u093e \u0930\u0902\u0917 \u092c\u0924\u093e\u0924\u0947 \u0939\u0948\u0902 \u091c\u094b \u0915\u093f\u0938\u0940 \u0926\u0942\u0938\u0930\u0947 \u0930\u0902\u0917 \u0915\u0940 \u0935\u0930\u094d\u0924\u0928\u0940 \u0915\u0930 \u0930\u0939\u093e \u0939\u094b \u2014 \u092a\u0922\u093c\u0928\u093e, \u0930\u0902\u0917 \u092c\u0924\u093e\u0928\u0947 \u092e\u0947\u0902 \u0935\u094d\u092f\u0924\u093f\u0915\u0930\u0923 \u0921\u093e\u0932 \u0926\u0947\u0924\u093e \u0939\u0948\u0964"],["\u092f\u0939 \u0915\u094d\u092f\u093e \u092e\u093e\u092a\u0924\u093e \u0939\u0948?","\u0905\u0935\u0930\u094b\u0927\u0915 \u0928\u093f\u092f\u0902\u0924\u094d\u0930\u0923 \u0914\u0930 \u091a\u092f\u0928\u093e\u0924\u094d\u092e\u0915 \u0927\u094d\u092f\u093e\u0928, \u091c\u094b \u0915\u093e\u0930\u094d\u092f\u0915\u093e\u0930\u0940 \u0915\u093e\u0930\u094d\u092f \u0915\u093e \u090f\u0915 \u092e\u0942\u0932 \u0939\u093f\u0938\u094d\u0938\u093e \u0939\u0948\u0964"],["\u0915\u094d\u092f\u093e \u092e\u0948\u0902 \u0907\u0938\u0947 \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u093f\u0924 \u0915\u0930 \u0938\u0915\u0924\u093e \u0939\u0942\u0901?","\u0906\u092a \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0947 \u0938\u093e\u0925 \u0905\u092a\u0928\u0940 \u0905\u092a\u0928\u0940 \u0935\u094d\u092f\u0924\u093f\u0915\u0930\u0923-\u0915\u0940\u092e\u0924 \u0918\u091f\u093e \u0938\u0915\u0924\u0947 \u0939\u0948\u0902; \u092a\u0930 \u0905\u0938\u0932-\u091c\u093c\u093f\u0902\u0926\u0917\u0940 \u0915\u0947 \u0906\u0924\u094d\u092e-\u0928\u093f\u092f\u0902\u0924\u094d\u0930\u0923 \u0924\u0915 \u0935\u094d\u092f\u093e\u092a\u0915 \u0939\u0938\u094d\u0924\u093e\u0902\u0924\u0930\u0923 \u0905\u091a\u094d\u091b\u0940 \u0924\u0930\u0939 \u0938\u093f\u0926\u094d\u0927 \u0928\u0939\u0940\u0902 \u0939\u0948\u0964"]],variants:"\u091a\u093f\u0930-\u092a\u0930\u093f\u091a\u093f\u0924 \u0930\u0902\u0917-\u0936\u092c\u094d\u0926; \u092d\u093e\u0935\u0928\u093e\u0924\u094d\u092e\u0915 Stroop (\u0930\u0902\u0917\u094b\u0902 \u0915\u0940 \u091c\u0917\u0939 \u092d\u093e\u0935\u0928\u093e\u0924\u094d\u092e\u0915 \u0936\u092c\u094d\u0926); \u0938\u0902\u0916\u094d\u092f\u093e\u0924\u094d\u092e\u0915 \u0914\u0930 \u0938\u094d\u0925\u093e\u0928\u093f\u0915 Stroop; \u0914\u0930 \u0909\u0932\u091f\u0947 \u0930\u0942\u092a \u091c\u0939\u093e\u0901 \u0906\u092a \u0936\u092c\u094d\u0926 \u092a\u0922\u093c\u0924\u0947 \u0939\u0948\u0902 \u0914\u0930 \u0938\u094d\u092f\u093e\u0939\u0940 \u0915\u094b \u0928\u091c\u093c\u0930\u0905\u0902\u0926\u093e\u091c\u093c \u0915\u0930\u0924\u0947 \u0939\u0948\u0902\u0964"},zh:{about:"\u8868\u793a\u989c\u8272\u7684\u8bcd\u88ab\u5370\u6210\u4e86\u4e0e\u4e4b\u4e0d\u7b26\u7684\u58a8\u6c34\u8272\u2014\u2014\u300c\u7ea2\u300d\u8fd9\u4e2a\u5b57\u662f\u7528\u84dd\u8272\u5199\u7684\u2014\u2014\u800c\u4f60\u5fc5\u987b\u8bf4\u51fa\u58a8\u6c34\u7684\u989c\u8272\uff0c\u800c\u4e0d\u662f\u8bfb\u51fa\u8fd9\u4e2a\u5b57\u3002\u8bf4\u51fa\u989c\u8272\uff0c\u610f\u5473\u7740\u8981\u538b\u5236\u4f4f\u90a3\u80a1\u81ea\u52a8\u60f3\u53bb\u8bfb\u5b57\u7684\u51b2\u52a8\u3002",benefit:"\u6291\u5236\u63a7\u5236\u2014\u2014\u538b\u5236\u4e00\u4e2a\u5feb\u901f\u3001\u81ea\u52a8\u7684\u53cd\u5e94\uff0c\u8f6c\u800c\u9009\u62e9\u4e00\u4e2a\u8f83\u6162\u3001\u5374\u4e0e\u76ee\u6807\u76f8\u5173\u7684\u53cd\u5e94\u2014\u2014\u5916\u52a0\u9009\u62e9\u6027\u6ce8\u610f\u548c\u52a0\u5de5\u901f\u5ea6\u3002",history:"\u5b83\u662f\u5fc3\u7406\u5b66\u4e2d\u88ab\u5f15\u7528\u5f97\u6700\u591a\u7684\u5b9e\u9a8c\u4e4b\u4e00\u3002\u81ea1930\u5e74\u4ee3\u4ee5\u6765\uff0c\u5b83\u5df2\u88ab\u6539\u7f16\u8fc7\u6570\u4ee5\u5343\u8ba1\u6b21\uff0c\u662f\u8861\u91cf\u6267\u884c\u529f\u80fd\u7684\u4e00\u9879\u6807\u51c6\u4e34\u5e8a\u4e0e\u7814\u7a76\u624b\u6bb5\u3002",creator:"\u7ea6\u7ff0\xb7\u91cc\u5fb7\u5229\xb7\u65af\u7279\u9c81\u666e\uff08John Ridley Stroop\uff09\uff0c\u4ed6\u57281935\u5e74\u7684\u8bba\u6587\u300a\u7cfb\u5217\u8a00\u8bed\u53cd\u5e94\u4e2d\u7684\u5e72\u6270\u7814\u7a76\u300b\uff08Studies of Interference in Serial Verbal Reactions\uff09\u4e2d\u63cf\u8ff0\u4e86\u8fd9\u4e00\u6548\u5e94\u3002",methods:"\u5148\u6c42\u51c6\u786e\uff0c\u518d\u6c42\u901f\u5ea6\u3002\u8981\u8ffd\u8e2a\u4f60\u7684\u300c\u5e72\u6270\u4ee3\u4ef7\u300d\u2014\u2014\u5373\u4e0d\u4e00\u81f4\uff08incongruent\uff09\u8bd5\u6b21\u76f8\u6bd4\u4e00\u81f4\u8bd5\u6b21\u6240\u591a\u82b1\u7684\u65f6\u95f4\u2014\u2014\u800c\u4e0d\u662f\u5355\u770b\u539f\u59cb\u53cd\u5e94\u65f6\u3002\u8ba9\u6bcf\u4e2a\u56de\u5408\u4fdd\u6301\u7b80\u77ed\uff0c\u4ee5\u514d\u75b2\u52b3\u628a\u9519\u8bef\u62ac\u9ad8\u3002",duration:"\u6bcf\u5468\u51e0\u6b21\uff0c\u6bcf\u6b21\u505a\u51e0\u4e2a\u7b80\u77ed\u7684\u56de\u5408\u3001\u51e0\u5206\u949f\u5373\u53ef\u3002\u968f\u7740\u8fd9\u79cd\u300c\u538b\u5236\u300d\u53d8\u5f97\u66f4\u9ad8\u6548\uff0c\u4f60\u7684\u5e72\u6270\u4ee3\u4ef7\u901a\u5e38\u4f1a\u5728\u6700\u521d\u51e0\u6b21\u7ec3\u4e60\u4e2d\u7f29\u5c0f\uff0c\u7136\u540e\u8d8b\u4e8e\u5e73\u7a33\u3002",research:"\u8fd9\u4e00\u6548\u5e94\u672c\u8eab\u575a\u5982\u78d0\u77f3\uff0c\u51e0\u4e4e\u5728\u6bcf\u4e2a\u4eba\u8eab\u4e0a\u90fd\u80fd\u91cd\u73b0\u3002\u8bad\u7ec3\u80fd\u53ef\u9760\u5730\u7f29\u5c0f\u4f60\u81ea\u5df1\u5728\u8fd9\u9879\u4efb\u52a1\u4e0a\u7684\u5e72\u6270\uff1b\u81f3\u4e8e\u8fd9\u80fd\u5426\u8fc1\u79fb\u5230\u65e5\u5e38\u81ea\u63a7\u4e0a\uff0c\u5219\u8981\u4e0d\u786e\u5b9a\u5f97\u591a\uff0c\u6240\u4ee5\u8bf7\u4e3a\u4e86\u8fd9\u9879\u5177\u4f53\u6280\u80fd\u53bb\u8bad\u7ec3\u5b83\uff0c\u800c\u4e0d\u662f\u6307\u671b\u5b83\u5e26\u6765\u4e00\u6b21\u5e7f\u6cdb\u7684\u610f\u5fd7\u529b\u5347\u7ea7\u3002",rec:"\u7528\u5b83\u6765\u6253\u78e8\u5728\u51b2\u7a81\u4e4b\u4e0b\u53c8\u51c6\u53c8\u5feb\u7684\u300c\u538b\u5236\u300d\u80fd\u529b\u3002\u4e00\u65e6\u9519\u8bef\u6500\u5347\u5c31\u7acb\u523b\u505c\u4e0b\u2014\u2014\u8349\u7387\u6362\u6765\u7684\u901f\u5ea6\u5e76\u4e0d\u662f\u8fd9\u9879\u6280\u80fd\u3002",faq:[["\u4ec0\u4e48\u662f\u65af\u7279\u9c81\u666e\u6548\u5e94\uff1f","\u5f53\u4f60\u8981\u8bf4\u51fa\u4e00\u4e2a\u989c\u8272\u8bcd\u7684\u58a8\u6c34\u989c\u8272\u3001\u800c\u8fd9\u4e2a\u8bcd\u62fc\u5199\u7684\u5374\u662f\u53e6\u4e00\u79cd\u989c\u8272\u65f6\uff0c\u6240\u4ea7\u751f\u7684\u90a3\u79cd\u53d8\u6162\u2014\u2014\u8bfb\u5b57\u5e72\u6270\u4e86\u8bf4\u8272\u3002"],["\u5b83\u8861\u91cf\u7684\u662f\u4ec0\u4e48\uff1f","\u6291\u5236\u63a7\u5236\u548c\u9009\u62e9\u6027\u6ce8\u610f\uff0c\u8fd9\u662f\u6267\u884c\u529f\u80fd\u7684\u4e00\u4e2a\u6838\u5fc3\u7ec4\u6210\u90e8\u5206\u3002"],["\u6211\u80fd\u8bad\u7ec3\u5b83\u5417\uff1f","\u4f60\u53ef\u4ee5\u901a\u8fc7\u7ec3\u4e60\u6765\u964d\u4f4e\u81ea\u5df1\u7684\u5e72\u6270\u4ee3\u4ef7\uff1b\u4f46\u8981\u8bf4\u5b83\u80fd\u5e7f\u6cdb\u8fc1\u79fb\u5230\u73b0\u5b9e\u751f\u6d3b\u4e2d\u7684\u81ea\u63a7\u4e0a\uff0c\u76ee\u524d\u5c1a\u672a\u5145\u5206\u786e\u7acb\u3002"]],variants:"\u7ecf\u5178\u7684\u989c\u8272\u8bcd\u7248\uff1b\u60c5\u7eea\u65af\u7279\u9c81\u666e\uff08\u7528\u60c5\u7eea\u8bcd\u53d6\u4ee3\u989c\u8272\uff09\uff1b\u6570\u5b57\u65af\u7279\u9c81\u666e\u548c\u7a7a\u95f4\u65af\u7279\u9c81\u666e\uff1b\u4ee5\u53ca\u53cd\u5411\u7248\u672c\u2014\u2014\u4f60\u8981\u8bfb\u51fa\u90a3\u4e2a\u5b57\u3001\u800c\u5ffd\u7565\u58a8\u6c34\u7684\u989c\u8272\u3002"}},"stroop-emotional":{ru:{about:"\u0412 \xab\u042d\u043c\u043e\u0446\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u043e\u043c \u0421\u0442\u0440\u0443\u043f\u0435\xbb \u0441\u043b\u043e\u0432\u0430 \u043f\u043e\u043a\u0430\u0437\u044b\u0432\u0430\u044e\u0442\u0441\u044f \u0440\u0430\u0437\u043d\u044b\u043c \u0446\u0432\u0435\u0442\u043e\u043c, \u0430 \u0432\u0430\u0448\u0430 \u0435\u0434\u0438\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u0430\u044f \u0437\u0430\u0434\u0430\u0447\u0430 \u2014 \u043a\u0430\u043a \u043c\u043e\u0436\u043d\u043e \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u043d\u0430\u0437\u0432\u0430\u0442\u044c \u0446\u0432\u0435\u0442, \u043d\u0435 \u043e\u0431\u0440\u0430\u0449\u0430\u044f \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f \u043d\u0430 \u0441\u043c\u044b\u0441\u043b \u0441\u043b\u043e\u0432\u0430. \u0425\u0438\u0442\u0440\u043e\u0441\u0442\u044c \u0432 \u0442\u043e\u043c, \u0447\u0442\u043e \u0447\u0430\u0441\u0442\u044c \u0441\u043b\u043e\u0432 \u044d\u043c\u043e\u0446\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u043e \u0437\u0430\u0440\u044f\u0436\u0435\u043d\u0430 (\xab\u043e\u043f\u0430\u0441\u043d\u043e\u0441\u0442\u044c\xbb, \xab\u043f\u0440\u043e\u0432\u0430\u043b\xbb, \xab\u0441\u043c\u0435\u0440\u0442\u044c\xbb), \u0430 \u0447\u0430\u0441\u0442\u044c \u043d\u0435\u0439\u0442\u0440\u0430\u043b\u044c\u043d\u0430 (\xab\u0441\u0442\u043e\u043b\xbb, \xab\u043e\u043a\u043d\u043e\xbb), \u0438 \u043f\u043e\u0447\u0442\u0438 \u0432\u0441\u0435 \u0437\u0430\u043c\u0435\u0442\u043d\u043e \u043c\u0435\u0434\u043b\u0435\u043d\u043d\u0435\u0435 \u0440\u0435\u0430\u0433\u0438\u0440\u0443\u044e\u0442 \u043d\u0430 \u0437\u0430\u0440\u044f\u0436\u0435\u043d\u043d\u044b\u0435, \u0445\u043e\u0442\u044f \u0438\u0445 \u0441\u043c\u044b\u0441\u043b \u043a \u0437\u0430\u0434\u0430\u043d\u0438\u044e \u043e\u0442\u043d\u043e\u0448\u0435\u043d\u0438\u044f \u043d\u0435 \u0438\u043c\u0435\u0435\u0442.",benefit:"\u0422\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u0438\u0437\u0431\u0438\u0440\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0435 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u0438 \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044c \u0440\u0435\u0430\u043a\u0446\u0438\u0438 \u0432 \u0443\u0441\u043b\u043e\u0432\u0438\u044f\u0445 \u043f\u043e\u043c\u0435\u0445\u0438 \u2014 \u0443\u043c\u0435\u043d\u0438\u0435 \u043f\u0440\u043e\u0434\u043e\u043b\u0436\u0430\u0442\u044c \u043f\u0440\u043e\u0441\u0442\u043e\u0435 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435, \u043f\u043e\u043a\u0430 \u043e\u0442\u0432\u043b\u0435\u043a\u0430\u044e\u0449\u0435\u0435, \u044d\u043c\u043e\u0446\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u043e \u0433\u0440\u043e\u043c\u043a\u043e\u0435 \u0441\u043b\u043e\u0432\u043e \u043f\u0435\u0440\u0435\u0442\u044f\u0433\u0438\u0432\u0430\u0435\u0442 \u0444\u043e\u043a\u0443\u0441 \u043d\u0430 \u0441\u0435\u0431\u044f. \u0417\u0430\u043e\u0434\u043d\u043e \u0434\u0430\u0451\u0442 \u043f\u0440\u043e\u0447\u0443\u0432\u0441\u0442\u0432\u043e\u0432\u0430\u0442\u044c, \u043a\u0430\u043a \u0437\u0430\u0440\u044f\u0436\u0435\u043d\u043d\u044b\u0435 \u0441\u043b\u043e\u0432\u0430 \u0443\u0432\u043e\u0434\u044f\u0442 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u043e\u0442 \u0441\u0443\u0442\u0438 \u0434\u0435\u043b\u0430.",history:"\u0417\u0430\u0434\u0430\u043d\u0438\u0435 \u0432\u044b\u0440\u043e\u0441\u043b\u043e \u043f\u0440\u044f\u043c\u043e \u0438\u0437 \u043a\u043b\u0430\u0441\u0441\u0438\u0447\u0435\u0441\u043a\u043e\u0433\u043e \u0446\u0432\u0435\u0442\u043e\u0441\u043b\u043e\u0432\u0435\u0441\u043d\u043e\u0433\u043e \u0442\u0435\u0441\u0442\u0430 \u0421\u0442\u0440\u0443\u043f\u0430: \u0432\u043c\u0435\u0441\u0442\u043e \u043d\u0430\u0437\u0432\u0430\u043d\u0438\u0439 \u0446\u0432\u0435\u0442\u043e\u0432 \u0432 \u043d\u0435\u0433\u043e \u043f\u043e\u0434\u0441\u0442\u0430\u0432\u0438\u043b\u0438 \u044d\u043c\u043e\u0446\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u043e \u0437\u043d\u0430\u0447\u0438\u043c\u044b\u0435 \u0441\u043b\u043e\u0432\u0430. \u041f\u043e\u0434\u0445\u043e\u0434 \u0440\u0430\u0437\u0432\u0435\u0440\u043d\u0443\u043b\u0441\u044f \u0432 1980-\u0445 \u0432 \u043a\u043b\u0438\u043d\u0438\u0447\u0435\u0441\u043a\u043e\u0439 \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u0438 \u2014 \u043e\u0434\u043d\u043e\u0439 \u0438\u0437 \u0440\u0430\u043d\u043d\u0438\u0445 \u043e\u043f\u043e\u0440\u043d\u044b\u0445 \u0440\u0430\u0431\u043e\u0442 \u0441\u0442\u0430\u043b\u043e \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u0435 \u0423\u043e\u0442\u0442\u0441\u0430, \u041c\u0430\u043a\u043a\u0435\u043d\u043d\u044b, \u0428\u0435\u0440\u0440\u043e\u043a\u0430 \u0438 \u0422\u0440\u0435\u0437\u0430\u0439\u0437 1986 \u0433\u043e\u0434\u0430 \u043f\u0440\u043e \u043d\u0430\u0437\u044b\u0432\u0430\u043d\u0438\u0435 \u0446\u0432\u0435\u0442\u0430 \u0443 \u043b\u044e\u0434\u0435\u0439 \u0441 \u0431\u043e\u044f\u0437\u043d\u044c\u044e \u043f\u0430\u0443\u043a\u043e\u0432, \u2014 \u0430 \u043a 1990-\u043c \u043e\u043d \u0441\u0442\u0430\u043b \u0441\u0442\u0430\u043d\u0434\u0430\u0440\u0442\u043d\u044b\u043c \u0438\u043d\u0441\u0442\u0440\u0443\u043c\u0435\u043d\u0442\u043e\u043c \u0438\u0437\u0443\u0447\u0435\u043d\u0438\u044f \u0442\u0440\u0435\u0432\u043e\u0433\u0438, \u0444\u043e\u0431\u0438\u0439, \u0442\u0440\u0430\u0432\u043c\u044b \u0438 \u0434\u0435\u043f\u0440\u0435\u0441\u0441\u0438\u0438.",creator:"\u0415\u0434\u0438\u043d\u043e\u0433\u043e \u0430\u0432\u0442\u043e\u0440\u0430 \u0443 \u044d\u043c\u043e\u0446\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u043e\u0439 \u0432\u0435\u0440\u0441\u0438\u0438 \u043d\u0435\u0442. \u041e\u043d\u0430 \u043f\u0440\u043e\u0438\u0441\u0445\u043e\u0434\u0438\u0442 \u043e\u0442 \u0438\u0441\u0445\u043e\u0434\u043d\u043e\u0433\u043e \u0446\u0432\u0435\u0442\u043e\u0441\u043b\u043e\u0432\u0435\u0441\u043d\u043e\u0433\u043e \u0442\u0435\u0441\u0442\u0430 \u0414\u0436. \u0420. \u0421\u0442\u0440\u0443\u043f\u0430 1935 \u0433\u043e\u0434\u0430; \u044d\u043c\u043e\u0446\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u0443\u044e \u0430\u0434\u0430\u043f\u0442\u0430\u0446\u0438\u044e \u0432 1980-\u0445 \u0440\u0430\u0437\u0432\u0438\u0432\u0430\u043b\u0438 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u0435\u0439 \u0442\u0440\u0435\u0432\u043e\u0433\u0438, \u0430 \u0432\u043b\u0438\u044f\u0442\u0435\u043b\u044c\u043d\u044b\u0439 \u043e\u0431\u0437\u043e\u0440, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u0437\u0430\u043a\u0440\u0435\u043f\u0438\u043b \u0438 \u043d\u0430\u0437\u0432\u0430\u043b \u043c\u0435\u0442\u043e\u0434, \u2014 \u0441\u0442\u0430\u0442\u044c\u044f \u0423\u0438\u043b\u044c\u044f\u043c\u0441\u0430, \u041c\u044d\u0442\u044c\u044e\u0441\u0430 \u0438 \u041c\u0430\u043a\u043b\u0430\u0443\u0434\u0430 1996 \u0433\u043e\u0434\u0430 \u0432 Psychological Bulletin.",methods:"\u0414\u0435\u0440\u0436\u0438\u0442\u0435\u0441\u044c \u0437\u0430 \u043e\u0434\u043d\u043e \u2014 \u0437\u0430 \u0446\u0432\u0435\u0442, \u0430 \u0441\u043b\u043e\u0432\u043e \u0432\u043e\u0441\u043f\u0440\u0438\u043d\u0438\u043c\u0430\u0439\u0442\u0435 \u043a\u0430\u043a \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0439 \u0448\u0443\u043c, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u0432\u044b \u043d\u0435 \u0447\u0438\u0442\u0430\u0435\u0442\u0435. \u0418\u0434\u0438\u0442\u0435 \u0440\u043e\u0432\u043d\u044b\u043c \u0442\u0435\u043c\u043f\u043e\u043c, \u0430 \u043d\u0435 \u043d\u0430 \u0433\u043e\u043d\u043a\u0435: \u0441\u043f\u0435\u0448\u043a\u0430 \u043a\u0430\u043a \u0440\u0430\u0437 \u0438 \u0441\u0431\u0438\u0432\u0430\u0435\u0442 \u043d\u0430 \u0437\u0430\u0440\u044f\u0436\u0435\u043d\u043d\u044b\u0445 \u0441\u043b\u043e\u0432\u0430\u0445; \u0441\u043f\u043e\u0442\u043a\u043d\u0443\u043b\u0438\u0441\u044c \u2014 \u0441\u0431\u0430\u0432\u044c\u0442\u0435 \u043d\u0430 \u0442\u0430\u043a\u0442 \u0438 \u0441\u043d\u043e\u0432\u0430 \u0437\u0430\u0446\u0435\u043f\u0438\u0442\u0435\u0441\u044c \u0437\u0430 \u0446\u0432\u0435\u0442 \u043a\u0440\u0430\u0441\u043a\u0438. \u0421\u043b\u0443\u0447\u0430\u0439\u043d\u043e\u0435 \u0447\u0435\u0440\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u0435 \u0437\u0430\u0440\u044f\u0436\u0435\u043d\u043d\u044b\u0445 \u0438 \u043d\u0435\u0439\u0442\u0440\u0430\u043b\u044c\u043d\u044b\u0445 \u0441\u043b\u043e\u0432 \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044c \u0436\u0451\u0441\u0442\u0447\u0435, \u0447\u0435\u043c \u043a\u043e\u0433\u0434\u0430 \u043e\u043d\u0438 \u0438\u0434\u0443\u0442 \u0431\u043b\u043e\u043a\u0430\u043c\u0438.",duration:"\u041b\u0443\u0447\u0448\u0435 \u0432\u0441\u0435\u0433\u043e \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u0435 \u043f\u043e\u0434\u0445\u043e\u0434\u044b, \u043f\u0440\u0438\u043c\u0435\u0440\u043d\u043e 3\u20135 \u043c\u0438\u043d\u0443\u0442, \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0440\u0430\u0437 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e. \u0423\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0442\u044c \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u043f\u0440\u043e\u0442\u0438\u0432 \u043f\u043e\u043c\u0435\u0445\u0438 \u0443\u0442\u043e\u043c\u0438\u0442\u0435\u043b\u044c\u043d\u043e, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u0437\u0430\u043a\u0430\u043d\u0447\u0438\u0432\u0430\u0439\u0442\u0435 \u0434\u043e \u0442\u043e\u0433\u043e, \u043a\u0430\u043a \u043d\u0430\u0447\u043d\u0451\u0442\u0435 \u0447\u0438\u0442\u0430\u0442\u044c \u0441\u043b\u043e\u0432\u0430 \u043d\u0430 \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0435, \u0438 \u0434\u0435\u0440\u0436\u0438\u0442\u0435 \u044d\u0442\u043e \u043a\u0430\u043a \u043e\u0434\u0438\u043d \u043f\u0443\u043d\u043a\u0442 \u0432 \u0440\u0430\u0437\u043d\u043e\u043e\u0431\u0440\u0430\u0437\u043d\u043e\u043c \u043d\u0430\u0431\u043e\u0440\u0435, \u0430 \u043d\u0435 \u043a\u0430\u043a \u0447\u0430\u0441\u043e\u0432\u0443\u044e \u0437\u0443\u0431\u0440\u0451\u0436\u043a\u0443.",research:"\u0422\u0432\u0451\u0440\u0434\u043e \u0434\u043e\u043a\u0430\u0437\u0430\u043d\u043e \u043d\u0435\u043c\u043d\u043e\u0433\u043e\u0435 \u0438 \u043e\u0436\u0438\u0434\u0430\u0435\u043c\u043e\u0435: \u0446\u0432\u0435\u0442 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043b\u044c\u043d\u043e \u043d\u0430\u0437\u044b\u0432\u0430\u044e\u0442 \u043c\u0435\u0434\u043b\u0435\u043d\u043d\u0435\u0435, \u043a\u043e\u0433\u0434\u0430 \u0441\u043b\u043e\u0432\u043e \u044d\u043c\u043e\u0446\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u043e \u0437\u0430\u0440\u044f\u0436\u0435\u043d\u043e, \u0438 \u044d\u0442\u043e \u0437\u0430\u043c\u0435\u0434\u043b\u0435\u043d\u0438\u0435 \u0441\u0438\u043b\u044c\u043d\u0435\u0435 \u0434\u043b\u044f \u0441\u043b\u043e\u0432, \u0437\u0430\u0434\u0435\u0432\u0430\u044e\u0449\u0438\u0445 \u043b\u0438\u0447\u043d\u0443\u044e \u0431\u043e\u043b\u044c\u043d\u0443\u044e \u0442\u0435\u043c\u0443 \u0447\u0435\u043b\u043e\u0432\u0435\u043a\u0430 (\u0443\u0433\u0440\u043e\u0437\u0430 \u2014 \u0443 \u0442\u0440\u0435\u0432\u043e\u0436\u043d\u044b\u0445, \u0441\u043b\u043e\u0432\u0430 \u043e \u0442\u0435\u043b\u0435 \u2014 \u043f\u0440\u0438 \u0440\u0430\u0441\u0441\u0442\u0440\u043e\u0439\u0441\u0442\u0432\u0430\u0445 \u043f\u0438\u0449\u0435\u0432\u043e\u0433\u043e \u043f\u043e\u0432\u0435\u0434\u0435\u043d\u0438\u044f \u0438 \u0442\u0430\u043a \u0434\u0430\u043b\u0435\u0435), \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u043c\u0435\u0442\u043e\u0434 \u0438 \u0446\u0435\u043d\u044f\u0442 \u043a\u0430\u043a \u0438\u0437\u043c\u0435\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0439 \u0438\u043d\u0441\u0442\u0440\u0443\u043c\u0435\u043d\u0442. \u0428\u0430\u0442\u043a\u043e \u0436\u0435 \u0441\u0430\u043c\u043e \u043f\u043e\u043f\u0443\u043b\u044f\u0440\u043d\u043e\u0435 \u043e\u0431\u044a\u044f\u0441\u043d\u0435\u043d\u0438\u0435: \u0437\u043d\u0430\u0447\u0438\u0442\u0435\u043b\u044c\u043d\u0443\u044e \u0447\u0430\u0441\u0442\u044c \u044d\u0444\u0444\u0435\u043a\u0442\u0430 \u0434\u0430\u044e\u0442 \u043e\u0431\u0449\u0435\u0435 \u0437\u0430\u043c\u0435\u0434\u043b\u0435\u043d\u0438\u0435 \u043e\u0442 \xab\u0443\u0433\u0440\u043e\u0437\u044b\xbb \u0438 \u043f\u0435\u0440\u0435\u043d\u043e\u0441 \u043d\u0430\u0441\u0442\u0440\u043e\u0439\u043a\u0438 \u043c\u0435\u0436\u0434\u0443 \u043f\u0440\u043e\u0431\u0430\u043c\u0438, \u0430 \u043d\u0435 \u043c\u0433\u043d\u043e\u0432\u0435\u043d\u043d\u044b\u0439 \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u0438\u0439 \u0437\u0430\u0445\u0432\u0430\u0442 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f; \u0432\u0435\u0440\u0441\u0438\u0438 \u0441 \u043c\u0430\u0441\u043a\u0438\u0440\u043e\u0432\u043a\u043e\u0439 \u0438 \u043f\u043e\u0434\u043f\u043e\u0440\u043e\u0433\u043e\u0432\u044b\u043c \u043f\u0440\u0435\u0434\u044a\u044f\u0432\u043b\u0435\u043d\u0438\u0435\u043c \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u044f\u0442\u0441\u044f \u043f\u043b\u043e\u0445\u043e; \u0430 \u0441\u0430\u043c\u044b\u0435 \u043a\u0440\u0443\u043f\u043d\u044b\u0435 \u044d\u0444\u0444\u0435\u043a\u0442\u044b \u0432 \u043c\u0435\u0442\u0430\u0430\u043d\u0430\u043b\u0438\u0437\u0435 70 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u0439 \u0434\u0430\u0432\u0430\u043b\u043e \u0431\u043b\u043e\u0447\u043d\u043e\u0435 \u043f\u0440\u0435\u0434\u044a\u044f\u0432\u043b\u0435\u043d\u0438\u0435. \u041d\u0435\u0442 \u0443\u0431\u0435\u0434\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0445 \u0434\u0430\u043d\u043d\u044b\u0445, \u0447\u0442\u043e \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0430 \u044d\u0442\u043e\u0433\u043e \u0437\u0430\u0434\u0430\u043d\u0438\u044f \u043e\u0431\u043e\u0441\u0442\u0440\u044f\u0435\u0442 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u0432 \u0446\u0435\u043b\u043e\u043c, \u043f\u043e\u0434\u043d\u0438\u043c\u0430\u0435\u0442 \u043d\u0430\u0441\u0442\u0440\u043e\u0435\u043d\u0438\u0435 \u0438\u043b\u0438 \u0441\u043d\u0438\u0436\u0430\u0435\u0442 \u0440\u0435\u0430\u043b\u044c\u043d\u0443\u044e \u044d\u043c\u043e\u0446\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u0443\u044e \u0440\u0435\u0430\u043a\u0442\u0438\u0432\u043d\u043e\u0441\u0442\u044c, \u0442\u0430\u043a \u0447\u0442\u043e \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u0435\u0441\u044c \u043a \u043d\u0435\u043c\u0443 \u043a\u0430\u043a \u043a \u043e\u043a\u043d\u0443 \u0432 \u0441\u043e\u0431\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0435 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435, \u0430 \u043d\u0435 \u043a\u0430\u043a \u043a \u0441\u043f\u043e\u0441\u043e\u0431\u0443 \u0435\u0433\u043e \u043f\u043e\u0447\u0438\u043d\u0438\u0442\u044c.",rec:"\u0418\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0439\u0442\u0435 \u043a\u0430\u043a \u043a\u043e\u0440\u043e\u0442\u043a\u0443\u044e \u0440\u0430\u0437\u043c\u0438\u043d\u043a\u0443, \u0447\u0442\u043e\u0431\u044b \u043f\u043e\u0447\u0443\u0432\u0441\u0442\u0432\u043e\u0432\u0430\u0442\u044c, \u043a\u0430\u043a \u0437\u0430\u0440\u044f\u0436\u0435\u043d\u043d\u044b\u0435 \u0441\u043b\u043e\u0432\u0430 \u0442\u043e\u0440\u043c\u043e\u0437\u044f\u0442 \u0444\u043e\u043a\u0443\u0441, \u0438 \u0438\u0434\u0438\u0442\u0435 \u0434\u0430\u043b\u044c\u0448\u0435; \u043d\u0435 \u0436\u0434\u0438\u0442\u0435, \u0447\u0442\u043e \u0441\u0442\u0430\u043d\u0435\u0442\u0435 \u0441\u043f\u043e\u043a\u043e\u0439\u043d\u0435\u0435 \u0438\u043b\u0438 \u0432\u043d\u0438\u043c\u0430\u0442\u0435\u043b\u044c\u043d\u0435\u0435 \u0432\u043e\u043e\u0431\u0449\u0435.",faq:[["\u041f\u043e\u0447\u0435\u043c\u0443 \u044f \u043c\u0435\u0434\u043b\u0435\u043d\u043d\u0435\u0435 \u043d\u0430 \u0441\u043b\u043e\u0432\u0430\u0445 \u0432\u0440\u043e\u0434\u0435 \xab\u043e\u043f\u0430\u0441\u043d\u043e\u0441\u0442\u044c\xbb, \u0445\u043e\u0442\u044f \u043d\u0430\u0437\u044b\u0432\u0430\u044e \u0442\u043e\u043b\u044c\u043a\u043e \u0446\u0432\u0435\u0442?","\u0417\u0430\u0440\u044f\u0436\u0435\u043d\u043d\u044b\u0435 \u0441\u043b\u043e\u0432\u0430 \u0443\u0441\u043f\u0435\u0432\u0430\u044e\u0442 \u043e\u0442\u0445\u0432\u0430\u0442\u0438\u0442\u044c \u0447\u0430\u0441\u0442\u044c \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f \u0438 \u043e\u0431\u0440\u0430\u0431\u043e\u0442\u043a\u0438 \u043f\u0440\u0435\u0436\u0434\u0435, \u0447\u0435\u043c \u0432\u044b \u0438\u0445 \u043f\u043e\u0434\u0430\u0432\u0438\u0442\u0435, \u0438 \u0440\u0435\u0430\u043a\u0446\u0438\u044f \u043d\u0430 \u0446\u0432\u0435\u0442 \u043f\u0440\u0438\u0445\u043e\u0434\u0438\u0442 \u043d\u0430 \u0434\u043e\u043b\u0438 \u0441\u0435\u043a\u0443\u043d\u0434\u044b \u043f\u043e\u0437\u0436\u0435. \u042d\u0442\u043e \u0437\u0430\u043f\u0430\u0437\u0434\u044b\u0432\u0430\u043d\u0438\u0435 \u0438 \u0435\u0441\u0442\u044c \u0441\u043c\u044b\u0441\u043b \u0437\u0430\u0434\u0430\u043d\u0438\u044f, \u0430 \u043d\u0435 \u0432\u0430\u0448\u0430 \u043e\u0448\u0438\u0431\u043a\u0430."],["\u0415\u0441\u043b\u0438 \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u044d\u0442\u043e, \u0441\u0442\u0430\u043d\u0443 \u043b\u0438 \u044f \u0441\u043f\u043e\u043a\u043e\u0439\u043d\u0435\u0435 \u0440\u0435\u0430\u0433\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u043d\u0430 \u0441\u0442\u0440\u0435\u0441\u0441\u043e\u0432\u044b\u0435 \u0441\u043b\u043e\u0432\u0430 \u0432 \u0436\u0438\u0437\u043d\u0438?","\u0423\u0431\u0435\u0434\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0445 \u0434\u0430\u043d\u043d\u044b\u0445 \u0437\u0430 \u044d\u0442\u043e \u043d\u0435\u0442. \u0417\u0430\u0434\u0430\u043d\u0438\u0435 \u0445\u043e\u0440\u043e\u0448\u043e \u0438\u0437\u043c\u0435\u0440\u044f\u0435\u0442 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u043a \u0437\u0430\u0440\u044f\u0436\u0435\u043d\u043d\u044b\u043c \u0441\u043b\u043e\u0432\u0430\u043c, \u043d\u043e \u043d\u0435 \u043f\u043e\u043a\u0430\u0437\u0430\u043d\u043e, \u0447\u0442\u043e \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0430 \u0441\u043d\u0438\u0436\u0430\u0435\u0442 \u043f\u043e\u0432\u0441\u0435\u0434\u043d\u0435\u0432\u043d\u0443\u044e \u044d\u043c\u043e\u0446\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u0443\u044e \u0440\u0435\u0430\u043a\u0442\u0438\u0432\u043d\u043e\u0441\u0442\u044c \u0438\u043b\u0438 \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0438\u0442\u0441\u044f \u0437\u0430 \u043f\u0440\u0435\u0434\u0435\u043b\u044b \u0441\u0430\u043c\u043e\u0433\u043e \u0437\u0430\u0434\u0430\u043d\u0438\u044f."],["\u0411\u043e\u043b\u044c\u0448\u043e\u0439 \u044d\u043c\u043e\u0446\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u044b\u0439 \u044d\u0444\u0444\u0435\u043a\u0442 \u0421\u0442\u0440\u0443\u043f\u0430 \u2014 \u044d\u0442\u043e \u043f\u0440\u0438\u0437\u043d\u0430\u043a, \u0447\u0442\u043e \u0441\u043e \u043c\u043d\u043e\u0439 \u0447\u0442\u043e-\u0442\u043e \u043d\u0435 \u0442\u0430\u043a?","\u041d\u0435\u0442. \u0423\u0441\u0438\u043b\u0435\u043d\u043d\u043e\u0435 \u0437\u0430\u043c\u0435\u0434\u043b\u0435\u043d\u0438\u0435 \u043d\u0430 \u043e\u0442\u0434\u0435\u043b\u044c\u043d\u044b\u0445 \u0442\u0435\u043c\u0430\u0445 \u0432\u0441\u0442\u0440\u0435\u0447\u0430\u0435\u0442\u0441\u044f \u0432 \u0447\u0430\u0441\u0442\u0438 \u043f\u0440\u043e\u0444\u0438\u043b\u0435\u0439 \u0442\u0440\u0435\u0432\u043e\u0433\u0438, \u0444\u043e\u0431\u0438\u0439 \u0438 \u0442\u0440\u0430\u0432\u043c\u044b, \u043d\u043e \u044d\u0442\u043e \u0441\u0438\u0433\u043d\u0430\u043b \u0434\u043b\u044f \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u0439 \u0438 \u0441\u043a\u0440\u0438\u043d\u0438\u043d\u0433\u0430 \u043f\u043e \u0433\u0440\u0443\u043f\u043f\u0430\u043c, \u0430 \u043d\u0435 \u0441\u0430\u043c\u043e\u0434\u0438\u0430\u0433\u043d\u043e\u0437, \u0438 \u043d\u0435\u043c\u0430\u043b\u044b\u0439 \u0440\u0430\u0437\u0431\u0440\u043e\u0441 \u2014 \u043f\u0440\u043e\u0441\u0442\u043e \u043d\u043e\u0440\u043c\u0430."]],variants:"\u0427\u0430\u0441\u0442\u044b\u0435 \u0432\u0430\u0440\u0438\u0430\u0446\u0438\u0438: \u043f\u043e\u0434\u043c\u0435\u043d\u044f\u044e\u0442 \u043d\u0430\u0431\u043e\u0440 \u0441\u043b\u043e\u0432 \u043f\u043e\u0434 \u043a\u043e\u043d\u043a\u0440\u0435\u0442\u043d\u0443\u044e \u0442\u0435\u043c\u0443 (\u0443\u0433\u0440\u043e\u0437\u0430, \u0441\u043e\u0446\u0438\u0430\u043b\u044c\u043d\u044b\u0435, \u043e\u0431\u0440\u0430\u0437 \u0442\u0435\u043b\u0430, \u0441\u0432\u044f\u0437\u0430\u043d\u043d\u044b\u0435 \u0441 \u0442\u0440\u0430\u0432\u043c\u043e\u0439 \u0438\u043b\u0438 \u0441 \u0437\u0430\u0432\u0438\u0441\u0438\u043c\u043e\u0441\u0442\u044c\u044e), \u043f\u043e\u043a\u0430\u0437\u044b\u0432\u0430\u044e\u0442 \u0441\u043b\u043e\u0432\u0430 \u0431\u043b\u043e\u043a\u0430\u043c\u0438 \u043e\u0434\u043d\u043e\u0433\u043e \u0442\u0438\u043f\u0430 \u0438\u043b\u0438 \u0432\u043f\u0435\u0440\u0435\u043c\u0435\u0448\u043a\u0443, \u0434\u0430\u044e\u0442 \u0441\u043b\u043e\u0432\u0430 \u043e\u0447\u0435\u043d\u044c \u043a\u0440\u0430\u0442\u043a\u043e \u043b\u0438\u0431\u043e \u043f\u043e\u0434 \u043c\u0430\u0441\u043a\u043e\u0439, \u0447\u0442\u043e\u0431\u044b \u043f\u0440\u043e\u0449\u0443\u043f\u0430\u0442\u044c \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u0443\u044e \u043e\u0431\u0440\u0430\u0431\u043e\u0442\u043a\u0443, \u0438\u043b\u0438 \u0437\u0430\u043c\u0435\u043d\u044f\u044e\u0442 \u0441\u043b\u043e\u0432\u0430 \u044d\u043c\u043e\u0446\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u044b\u043c\u0438 \u043b\u0438\u0446\u0430\u043c\u0438 \u0438 \u043a\u0430\u0440\u0442\u0438\u043d\u043a\u0430\u043c\u0438 \u0432 \u0432\u0435\u0440\u0441\u0438\u0438 \xab\u0441\u043b\u043e\u0432\u043e \u2014 \u0438\u0437\u043e\u0431\u0440\u0430\u0436\u0435\u043d\u0438\u0435\xbb."},en:{about:"Emotional Stroop shows you words printed in different ink colours, and your only job is to name the colour as fast as you can while ignoring what the word means. The catch is that some words are emotionally charged (\"danger\", \"failure\", \"death\") and some are neutral (\"table\", \"window\"), and most people are measurably slower on the charged ones, even though the meaning is irrelevant to the task.",benefit:"It trains selective attention and response control under interference, specifically the ability to keep doing a simple task while a distracting, emotionally loud word competes for your focus. It also gives you a felt sense of how charged language pulls attention away from the matter at hand.",history:"It grew directly out of the classic colour-word Stroop task by swapping the colour words for emotionally meaningful ones. The approach took off in the 1980s in clinical psychology, with Watts, McKenna, Sharrock and Trezise's 1986 study of colour-naming in spider phobics among the early landmarks, and through the 1990s it became a standard tool for studying anxiety, phobia, trauma and depression.",creator:"There is no single inventor of the emotional version. It descends from J. R. Stroop's original 1935 colour-word task; the emotional adaptation was developed by several anxiety researchers in the 1980s, and the influential review that named and consolidated the method is Williams, Mathews and MacLeod's 1996 paper in Psychological Bulletin.",methods:"Lock onto one thing only, the colour, and treat the word as visual noise you never read. Keep a steady rhythm rather than racing, since rushing makes you trip on the charged words; if you stumble, slow down by a beat and re-anchor on the ink. Mixing charged and neutral words randomly trains tighter trial-by-trial control than grouping them in blocks.",duration:"Short sessions work best, roughly 3 to 5 minutes, a few times a week. It is taxing to concentrate against interference, so stop before the point where you start reading words on autopilot, and treat it as one item in a varied routine rather than something to grind for an hour.",research:"What is solid is narrow and unsurprising: people reliably name colours more slowly when the word is emotionally charged, and this slowdown is larger for words tied to a person's own concern (threat for anxious people, body words for eating disorders, and so on), which is why it is a respected measurement tool. What is shaky is the popular story behind it, because a generic threat-driven slowdown and carry-over between trials explain much of the effect rather than a fast automatic attentional grab, the masked or subliminal versions replicate poorly, and the largest effects in a meta-analysis of 70 studies came from blocked presentation. There is no good evidence that practising it sharpens general attention, lifts mood or reduces real-world emotional reactivity, so treat it as a window onto your own attention, not a fix for it.",rec:"Use it as a brief warm-up to feel how charged words drag on focus, then move on; do not expect it to make you calmer or generally more attentive.",faq:[["Why am I slower on words like \"danger\" even though I'm only naming the colour?","Charged words grab a slice of attention and processing before you can suppress them, so the colour response arrives a fraction of a second late. That lag is the whole point of the task, not a mistake on your part."],["Does training this make me less reactive to stressful words in real life?","There's no good evidence for that. The task is solid at measuring attention to charged words, but practising it has not been shown to lower everyday emotional reactivity or to transfer beyond the task itself."],["Is a big emotional Stroop effect a sign something is wrong with me?","No. A larger slowdown on certain themes shows up in some anxiety, phobia and trauma profiles, but it is a research-and-screening signal across groups, not a self-diagnosis, and plenty of variation is just normal."]],variants:"Common variations swap the word set for a particular theme (threat, social, body image, trauma-related, or addiction cues), present words in blocks of one type versus randomly mixed, flash words very briefly or masked to probe automatic processing, or replace words with emotional faces or pictures in a picture-word version."},es:{about:"Emotional Stroop te muestra palabras impresas en distintos colores de tinta, y tu \xfanica tarea es nombrar el color lo m\xe1s r\xe1pido posible ignorando lo que la palabra significa. La trampa es que algunas palabras est\xe1n cargadas emocionalmente (\"peligro\", \"fracaso\", \"muerte\") y otras son neutras (\"mesa\", \"ventana\"), y la mayor\xeda de la gente va de forma mensurable m\xe1s lenta con las cargadas, aunque su significado sea irrelevante para la tarea.",benefit:"Entrena la atenci\xf3n selectiva y el control de la respuesta bajo interferencia, en concreto la capacidad de seguir haciendo una tarea sencilla mientras una palabra distractora y emocionalmente estridente compite por tu foco. Adem\xe1s te da una sensaci\xf3n palpable de c\xf3mo el lenguaje cargado desv\xeda la atenci\xf3n del asunto que tienes entre manos.",history:"Surgi\xf3 directamente de la cl\xe1sica tarea de Stroop de color y palabra, sustituyendo las palabras de color por otras con carga emocional. El enfoque despeg\xf3 en los a\xf1os ochenta en la psicolog\xeda cl\xednica, con el estudio de Watts, McKenna, Sharrock y Trezise de 1986 sobre la denominaci\xf3n de colores en personas con fobia a las ara\xf1as entre los primeros hitos, y a lo largo de los a\xf1os noventa se convirti\xf3 en una herramienta est\xe1ndar para estudiar la ansiedad, la fobia, el trauma y la depresi\xf3n.",creator:"No hay un \xfanico inventor de la versi\xf3n emocional. Desciende de la tarea original de color y palabra de J. R. Stroop de 1935; la adaptaci\xf3n emocional la desarrollaron varios investigadores de la ansiedad en los a\xf1os ochenta, y la influyente revisi\xf3n que dio nombre y consolid\xf3 el m\xe9todo es el art\xedculo de Williams, Mathews y MacLeod de 1996 en Psychological Bulletin.",methods:"F\xedjate en una sola cosa, el color, y trata la palabra como un ruido visual que nunca llegas a leer. Mant\xe9n un ritmo constante en lugar de correr, ya que precipitarte hace que tropieces con las palabras cargadas; si te trabas, frena un instante y vuelve a anclarte en la tinta. Mezclar palabras cargadas y neutras al azar entrena un control m\xe1s fino, ensayo a ensayo, que agruparlas en bloques.",duration:"Las sesiones cortas funcionan mejor, en torno a 3 a 5 minutos, unas cuantas veces por semana. Concentrarse contra la interferencia es exigente, as\xed que para antes del punto en que empiezas a leer las palabras en piloto autom\xe1tico, y t\xf3malo como un elemento m\xe1s de una rutina variada en lugar de algo que machacar durante una hora.",research:"Lo s\xf3lido es limitado y poco sorprendente: la gente nombra los colores de forma fiable m\xe1s despacio cuando la palabra est\xe1 cargada emocionalmente, y ese frenazo es mayor con las palabras ligadas a la propia preocupaci\xf3n de la persona (la amenaza en las personas ansiosas, las palabras sobre el cuerpo en los trastornos alimentarios, etc\xe9tera), y por eso es una herramienta de medici\xf3n respetada. Lo endeble es la historia popular que hay detr\xe1s, porque un frenazo gen\xe9rico provocado por la amenaza y el arrastre entre ensayos explican buena parte del efecto, m\xe1s que una captaci\xf3n atencional r\xe1pida y autom\xe1tica; las versiones enmascaradas o subliminales se replican mal, y los mayores efectos en un metaan\xe1lisis de 70 estudios provinieron de la presentaci\xf3n en bloques. No hay buena evidencia de que practicarlo agudice la atenci\xf3n general, mejore el estado de \xe1nimo o reduzca la reactividad emocional en la vida real, as\xed que t\xf3malo como una ventana a tu propia atenci\xf3n, no como un remedio para ella.",rec:"\xdasalo como un breve calentamiento para sentir c\xf3mo las palabras cargadas lastran el foco, y luego sigue adelante; no esperes que te vuelva m\xe1s calmado ni m\xe1s atento en general.",faq:[["\xbfPor qu\xe9 voy m\xe1s lento con palabras como \"peligro\" aunque solo est\xe9 nombrando el color?","Las palabras cargadas se llevan una porci\xf3n de atenci\xf3n y procesamiento antes de que puedas suprimirlas, as\xed que la respuesta del color llega una fracci\xf3n de segundo tarde. Ese retraso es justamente el objetivo de la tarea, no un fallo tuyo."],["\xbfEntrenar esto me hace menos reactivo a las palabras estresantes en la vida real?","No hay buena evidencia de ello. La tarea es s\xf3lida para medir la atenci\xf3n a las palabras cargadas, pero no se ha demostrado que practicarla reduzca la reactividad emocional cotidiana ni que se transfiera m\xe1s all\xe1 de la propia tarea."],["\xbfUn gran efecto Stroop emocional es se\xf1al de que algo va mal en m\xed?","No. Un frenazo mayor ante ciertos temas aparece en algunos perfiles de ansiedad, fobia y trauma, pero es una se\xf1al de investigaci\xf3n y de cribado entre grupos, no un autodiagn\xf3stico, y buena parte de la variaci\xf3n es simplemente normal."]],variants:"Las variaciones habituales cambian el conjunto de palabras por un tema concreto (amenaza, social, imagen corporal, relacionado con el trauma o se\xf1ales de adicci\xf3n), presentan las palabras en bloques de un solo tipo frente a una mezcla aleatoria, las muestran muy brevemente o enmascaradas para sondear el procesamiento autom\xe1tico, o sustituyen las palabras por caras o im\xe1genes emocionales en una versi\xf3n de imagen y palabra."},de:{about:"Der Emotionale Stroop zeigt dir W\xf6rter, die in verschiedenen Tintenfarben gedruckt sind, und deine einzige Aufgabe ist es, die Farbe so schnell wie m\xf6glich zu benennen und dabei zu ignorieren, was das Wort bedeutet. Der Haken: Manche W\xf6rter sind emotional aufgeladen (\"Gefahr\", \"Versagen\", \"Tod\") und manche neutral (\"Tisch\", \"Fenster\"), und die meisten Menschen sind bei den aufgeladenen messbar langsamer, obwohl die Bedeutung f\xfcr die Aufgabe ohne Belang ist.",benefit:"Trainiert werden die selektive Aufmerksamkeit und die Reaktionskontrolle unter St\xf6rung, konkret die F\xe4higkeit, eine einfache Aufgabe weiterzuf\xfchren, w\xe4hrend ein ablenkendes, emotional lautes Wort um deinen Fokus konkurriert. Es vermittelt dir au\xdferdem ein sp\xfcrbares Gef\xfchl daf\xfcr, wie aufgeladene Sprache die Aufmerksamkeit von der eigentlichen Sache wegzieht.",history:"Er ging unmittelbar aus der klassischen Farb-Wort-Stroop-Aufgabe hervor, indem die Farbw\xf6rter durch emotional bedeutsame ersetzt wurden. Der Ansatz nahm in den 1980er-Jahren in der klinischen Psychologie Fahrt auf, wobei die Studie von Watts, McKenna, Sharrock und Trezise aus dem Jahr 1986 zum Farbbenennen bei Spinnenphobikern zu den fr\xfchen Meilensteinen z\xe4hlt, und in den 1990er-Jahren wurde er zu einem Standardwerkzeug f\xfcr die Untersuchung von Angst, Phobie, Trauma und Depression.",creator:"Es gibt keinen einzelnen Erfinder der emotionalen Version. Sie geht auf J. R. Stroops urspr\xfcngliche Farb-Wort-Aufgabe von 1935 zur\xfcck; die emotionale Anpassung wurde in den 1980er-Jahren von mehreren Angstforschenden entwickelt, und die einflussreiche \xdcbersichtsarbeit, die die Methode benannte und zusammenf\xfchrte, ist die Arbeit von Williams, Mathews und MacLeod aus dem Jahr 1996 im Psychological Bulletin.",methods:"Fixiere nur eine Sache, die Farbe, und behandle das Wort als visuelles Rauschen, das du nie liest. Halte einen gleichm\xe4\xdfigen Rhythmus, statt zu rasen, denn Hetzen l\xe4sst dich \xfcber die aufgeladenen W\xf6rter stolpern; wenn du ins Stocken ger\xe4tst, werde eine Spur langsamer und verankere dich wieder an der Tinte. Aufgeladene und neutrale W\xf6rter zuf\xe4llig zu mischen trainiert eine engere Kontrolle von Durchgang zu Durchgang, als sie in Bl\xf6cken zu gruppieren.",duration:"Kurze Sitzungen funktionieren am besten, rund 3 bis 5 Minuten, ein paar Mal die Woche. Es ist anstrengend, sich gegen die St\xf6rung zu konzentrieren, also h\xf6r auf, bevor du anf\xe4ngst, W\xf6rter im Autopilot zu lesen, und behandle es als einen Baustein einer abwechslungsreichen Routine statt als etwas, das man eine Stunde lang durchackert.",research:"Was solide ist, ist eng und wenig \xfcberraschend: Menschen benennen Farben zuverl\xe4ssig langsamer, wenn das Wort emotional aufgeladen ist, und diese Verlangsamung ist gr\xf6\xdfer bei W\xf6rtern, die mit dem eigenen Anliegen einer Person verkn\xfcpft sind (Bedrohung bei \xe4ngstlichen Menschen, K\xf6rperw\xf6rter bei Essst\xf6rungen und so weiter), weshalb er ein anerkanntes Messwerkzeug ist. Wacklig ist die popul\xe4re Erz\xe4hlung dahinter, denn eine generische, durch Bedrohung ausgel\xf6ste Verlangsamung und \xdcbertragungseffekte zwischen Durchg\xe4ngen erkl\xe4ren einen Gro\xdfteil des Effekts eher als ein schnelles, automatisches Erfassen der Aufmerksamkeit, die maskierten oder unterschwelligen Versionen lassen sich schlecht replizieren, und die gr\xf6\xdften Effekte in einer Metaanalyse von 70 Studien stammten aus geblockter Darbietung. Es gibt keine guten Belege daf\xfcr, dass sein \xdcben die allgemeine Aufmerksamkeit sch\xe4rft, die Stimmung hebt oder die emotionale Reaktivit\xe4t im Alltag senkt, behandle ihn also als Fenster auf deine eigene Aufmerksamkeit, nicht als Mittel, sie zu reparieren.",rec:"Nutze ihn als kurzes Aufw\xe4rmen, um zu sp\xfcren, wie aufgeladene W\xf6rter am Fokus zerren, und geh dann weiter; erwarte nicht, dass er dich ruhiger oder allgemein aufmerksamer macht.",faq:[["Warum bin ich bei W\xf6rtern wie \"Gefahr\" langsamer, obwohl ich nur die Farbe benenne?","Aufgeladene W\xf6rter rei\xdfen einen Teil der Aufmerksamkeit und Verarbeitung an sich, bevor du sie unterdr\xfccken kannst, sodass die Farbantwort einen Sekundenbruchteil zu sp\xe4t eintrifft. Diese Verz\xf6gerung ist der ganze Sinn der Aufgabe, kein Fehler deinerseits."],["Macht mich das Training weniger reaktiv auf belastende W\xf6rter im echten Leben?","Daf\xfcr gibt es keine guten Belege. Die Aufgabe ist solide darin, die Aufmerksamkeit auf aufgeladene W\xf6rter zu messen, aber es ist nicht gezeigt, dass ihr \xdcben die allt\xe4gliche emotionale Reaktivit\xe4t senkt oder sich \xfcber die Aufgabe selbst hinaus \xfcbertr\xe4gt."],["Ist ein gro\xdfer emotionaler Stroop-Effekt ein Zeichen daf\xfcr, dass mit mir etwas nicht stimmt?","Nein. Eine gr\xf6\xdfere Verlangsamung bei bestimmten Themen zeigt sich in manchen Angst-, Phobie- und Traumaprofilen, aber sie ist ein Forschungs- und Screening-Signal \xfcber Gruppen hinweg, keine Selbstdiagnose, und ein gutes St\xfcck Schwankung ist einfach normal."]],variants:"G\xe4ngige Varianten tauschen den Wortsatz gegen ein bestimmtes Thema aus (Bedrohung, Soziales, K\xf6rperbild, traumabezogene oder suchtbezogene Reize), pr\xe4sentieren W\xf6rter in Bl\xf6cken eines Typs versus zuf\xe4llig gemischt, blitzen W\xf6rter sehr kurz oder maskiert auf, um die automatische Verarbeitung zu pr\xfcfen, oder ersetzen W\xf6rter durch emotionale Gesichter oder Bilder in einer Bild-Wort-Version."},pt:{about:"O Stroop Emocional mostra a voc\xea palavras impressas em cores de tinta diferentes, e a sua \xfanica tarefa \xe9 dizer a cor o mais r\xe1pido poss\xedvel, ignorando o que a palavra significa. O detalhe \xe9 que algumas palavras t\xeam carga emocional (\"perigo\", \"fracasso\", \"morte\") e outras s\xe3o neutras (\"mesa\", \"janela\"), e a maioria das pessoas \xe9 mensuravelmente mais lenta com as carregadas, mesmo que o significado seja irrelevante para a tarefa.",benefit:"Treina a aten\xe7\xe3o seletiva e o controle da resposta sob interfer\xeancia, especificamente a capacidade de seguir fazendo uma tarefa simples enquanto uma palavra distraidora e emocionalmente barulhenta disputa o seu foco. Tamb\xe9m te d\xe1 uma sensa\xe7\xe3o concreta de como a linguagem carregada puxa a aten\xe7\xe3o para longe do que est\xe1 em m\xe3os.",history:"Surgiu diretamente da cl\xe1ssica tarefa Stroop de cor-palavra, trocando as palavras de cor por palavras emocionalmente significativas. A abordagem decolou na d\xe9cada de 1980 na psicologia cl\xednica, com o estudo de 1986 de Watts, McKenna, Sharrock e Trezise sobre a nomea\xe7\xe3o de cores em f\xf3bicos de aranha entre os marcos iniciais, e ao longo dos anos 1990 tornou-se uma ferramenta padr\xe3o para estudar ansiedade, fobia, trauma e depress\xe3o.",creator:"N\xe3o h\xe1 um \xfanico inventor da vers\xe3o emocional. Ela descende da tarefa original de cor-palavra de J. R. Stroop, de 1935; a adapta\xe7\xe3o emocional foi desenvolvida por v\xe1rios pesquisadores da ansiedade na d\xe9cada de 1980, e a revis\xe3o influente que nomeou e consolidou o m\xe9todo \xe9 o artigo de 1996 de Williams, Mathews e MacLeod no Psychological Bulletin.",methods:"Fixe-se em uma \xfanica coisa, a cor, e trate a palavra como um ru\xeddo visual que voc\xea jamais l\xea. Mantenha um ritmo constante em vez de correr, j\xe1 que a pressa te faz trope\xe7ar nas palavras carregadas; se voc\xea trope\xe7ar, desacelere um instante e se reancore na tinta. Misturar palavras carregadas e neutras de forma aleat\xf3ria treina um controle tentativa a tentativa mais apurado do que agrup\xe1-las em blocos.",duration:"Sess\xf5es curtas funcionam melhor, mais ou menos 3 a 5 minutos, algumas vezes por semana. \xc9 desgastante concentrar-se contra a interfer\xeancia, ent\xe3o pare antes do ponto em que voc\xea come\xe7a a ler palavras no piloto autom\xe1tico, e encare como um item de uma rotina variada, n\xe3o como algo para insistir por uma hora.",research:"O que \xe9 s\xf3lido \xe9 limitado e pouco surpreendente: as pessoas nomeiam cores de forma confiavelmente mais lenta quando a palavra tem carga emocional, e essa lentid\xe3o \xe9 maior para palavras ligadas \xe0 pr\xf3pria preocupa\xe7\xe3o da pessoa (amea\xe7a para os ansiosos, palavras sobre o corpo para transtornos alimentares, e assim por diante), raz\xe3o pela qual \xe9 uma ferramenta de medi\xe7\xe3o respeitada. O que \xe9 fr\xe1gil \xe9 a hist\xf3ria popular por tr\xe1s disso, porque uma lentid\xe3o gen\xe9rica provocada por amea\xe7a e o arrasto entre tentativas explicam boa parte do efeito, em vez de uma captura atencional r\xe1pida e autom\xe1tica, as vers\xf5es mascaradas ou subliminares replicam mal, e os maiores efeitos numa meta-an\xe1lise de 70 estudos vieram da apresenta\xe7\xe3o em blocos. N\xe3o h\xe1 boa evid\xeancia de que pratic\xe1-lo afie a aten\xe7\xe3o geral, melhore o humor ou reduza a reatividade emocional no mundo real, ent\xe3o encare-o como uma janela para a sua pr\xf3pria aten\xe7\xe3o, n\xe3o como um conserto para ela.",rec:"Use como um breve aquecimento para sentir como as palavras carregadas pesam sobre o foco, e depois siga em frente; n\xe3o espere que ele te deixe mais calmo ou mais atento de modo geral.",faq:[["Por que fico mais lento em palavras como \"perigo\", mesmo s\xf3 nomeando a cor?","As palavras carregadas capturam uma fatia da aten\xe7\xe3o e do processamento antes que voc\xea consiga suprimi-las, ent\xe3o a resposta da cor chega uma fra\xe7\xe3o de segundo atrasada. Esse atraso \xe9 justamente o ponto da tarefa, n\xe3o um erro da sua parte."],["Treinar isso me deixa menos reativo a palavras estressantes na vida real?","N\xe3o h\xe1 boa evid\xeancia disso. A tarefa \xe9 s\xf3lida para medir a aten\xe7\xe3o a palavras carregadas, mas n\xe3o se demonstrou que pratic\xe1-la reduza a reatividade emocional do dia a dia ou se transfira para al\xe9m da pr\xf3pria tarefa."],["Um efeito Stroop emocional grande \xe9 sinal de que h\xe1 algo errado comigo?","N\xe3o. Uma lentid\xe3o maior em certos temas aparece em alguns perfis de ansiedade, fobia e trauma, mas \xe9 um sinal de pesquisa e triagem entre grupos, n\xe3o um autodiagn\xf3stico, e boa parte da varia\xe7\xe3o \xe9 simplesmente normal."]],variants:"As varia\xe7\xf5es comuns trocam o conjunto de palavras por um tema espec\xedfico (amea\xe7a, social, imagem corporal, relacionado a trauma ou pistas de depend\xeancia), apresentam palavras em blocos de um \xfanico tipo versus misturadas ao acaso, exibem palavras por um tempo muito breve ou mascaradas para sondar o processamento autom\xe1tico, ou substituem as palavras por rostos ou imagens emocionais numa vers\xe3o palavra-imagem."},hi:{about:"Emotional Stroop \u092e\u0947\u0902 \u0906\u092a\u0915\u094b \u0905\u0932\u0917-\u0905\u0932\u0917 \u0938\u094d\u092f\u093e\u0939\u0940 \u0915\u0947 \u0930\u0902\u0917\u094b\u0902 \u092e\u0947\u0902 \u091b\u092a\u0947 \u0936\u092c\u094d\u0926 \u0926\u093f\u0916\u093e\u090f \u091c\u093e\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u0906\u092a\u0915\u093e \u0907\u0915\u0932\u094c\u0924\u093e \u0915\u093e\u092e \u0939\u0948 \u0936\u092c\u094d\u0926 \u0915\u093e \u092e\u0924\u0932\u092c \u0905\u0928\u0926\u0947\u0916\u093e \u0915\u0930\u0915\u0947 \u091c\u093f\u0924\u0928\u0940 \u091c\u0932\u094d\u0926\u0940 \u0939\u094b \u0938\u0915\u0947 \u0909\u0938\u0915\u093e \u0930\u0902\u0917 \u092c\u0924\u093e\u0928\u093e\u0964 \u092a\u0947\u091a \u092f\u0939 \u0939\u0948 \u0915\u093f \u0915\u0941\u091b \u0936\u092c\u094d\u0926 \u092d\u093e\u0935\u0928\u093e\u0924\u094d\u092e\u0915 \u0930\u0942\u092a \u0938\u0947 \u092d\u093e\u0930\u0940 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902 (\"\u0916\u093c\u0924\u0930\u093e\", \"\u0928\u093e\u0915\u093e\u092e\u0940\", \"\u092e\u094c\u0924\") \u0914\u0930 \u0915\u0941\u091b \u0924\u091f\u0938\u094d\u0925 (\"\u092e\u0947\u091c\u093c\", \"\u0916\u093f\u0921\u093c\u0915\u0940\"), \u0914\u0930 \u091c\u093c\u094d\u092f\u093e\u0926\u093e\u0924\u0930 \u0932\u094b\u0917 \u092d\u093e\u0930\u0940 \u0936\u092c\u094d\u0926\u094b\u0902 \u092a\u0930 \u092e\u093e\u092a\u0947 \u091c\u093e \u0938\u0915\u0928\u0947 \u0932\u093e\u092f\u0915\u093c \u0927\u0940\u092e\u0947 \u092a\u0921\u093c \u091c\u093e\u0924\u0947 \u0939\u0948\u0902 \u2014 \u092d\u0932\u0947 \u0939\u0940 \u0936\u092c\u094d\u0926 \u0915\u093e \u0905\u0930\u094d\u0925 \u0907\u0938 \u0915\u093e\u092e \u0938\u0947 \u092c\u093f\u0932\u0915\u0941\u0932 \u092c\u0947\u092e\u0924\u0932\u092c \u0939\u094b\u0964",benefit:"\u092f\u0939 \u0926\u0916\u093c\u0932 \u0915\u0947 \u092c\u0940\u091a \u091a\u092f\u0928\u093e\u0924\u094d\u092e\u0915 \u0927\u094d\u092f\u093e\u0928 \u0914\u0930 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0928\u093f\u092f\u0902\u0924\u094d\u0930\u0923 \u0938\u093e\u0927\u0924\u093e \u0939\u0948 \u2014 \u0916\u093c\u093e\u0938\u0915\u0930 \u092f\u0939 \u0915\u094d\u0937\u092e\u0924\u093e \u0915\u093f \u090f\u0915 \u092d\u093e\u0935\u0928\u093e\u0924\u094d\u092e\u0915 \u0930\u0942\u092a \u0938\u0947 \u0936\u094b\u0930 \u092e\u091a\u093e\u0924\u093e \u0936\u092c\u094d\u0926 \u091c\u092c \u0906\u092a\u0915\u0947 \u0927\u094d\u092f\u093e\u0928 \u0915\u094b \u0916\u0940\u0902\u091a\u0928\u0947 \u0915\u0940 \u0939\u094b\u0921\u093c \u0915\u0930 \u0930\u0939\u093e \u0939\u094b, \u0924\u092c \u092d\u0940 \u0906\u092a \u090f\u0915 \u0938\u0940\u0927\u093e-\u0938\u093e\u0926\u093e \u0915\u093e\u092e \u0915\u0930\u0924\u0947 \u0930\u0939\u0947\u0902\u0964 \u0938\u093e\u0925 \u0939\u0940 \u092f\u0939 \u0906\u092a\u0915\u094b \u092f\u0939 \u090f\u0939\u0938\u093e\u0938 \u092d\u0940 \u0915\u0930\u093e\u0924\u093e \u0939\u0948 \u0915\u093f \u092d\u093e\u0930\u0940 \u0936\u092c\u094d\u0926 \u0915\u0948\u0938\u0947 \u0927\u094d\u092f\u093e\u0928 \u0915\u094b \u0905\u0938\u0932\u0940 \u0915\u093e\u092e \u0938\u0947 \u0916\u0940\u0902\u091a \u0932\u0947\u0924\u0947 \u0939\u0948\u0902\u0964",history:"\u092f\u0939 \u0938\u0940\u0927\u0947 \u0915\u094d\u0932\u093e\u0938\u093f\u0915 \u0930\u0902\u0917-\u0936\u092c\u094d\u0926 Stroop \u091f\u093e\u0938\u094d\u0915 \u0938\u0947 \u0928\u093f\u0915\u0932\u093e \u2014 \u092c\u0938 \u0930\u0902\u0917\u094b\u0902 \u0915\u0947 \u0928\u093e\u092e\u094b\u0902 \u0915\u0940 \u091c\u0917\u0939 \u092d\u093e\u0935\u0928\u093e\u0924\u094d\u092e\u0915 \u0905\u0930\u094d\u0925 \u0935\u093e\u0932\u0947 \u0936\u092c\u094d\u0926 \u0930\u0916 \u0926\u093f\u090f \u0917\u090f\u0964 \u092f\u0939 \u0924\u0930\u0940\u0915\u093c\u093e 1980 \u0915\u0947 \u0926\u0936\u0915 \u092e\u0947\u0902 \u0915\u094d\u0932\u093f\u0928\u093f\u0915\u0932 \u092e\u0928\u094b\u0935\u093f\u091c\u094d\u091e\u093e\u0928 \u092e\u0947\u0902 \u091c\u093c\u094b\u0930 \u092a\u0915\u0921\u093c\u0928\u0947 \u0932\u0917\u093e; \u0936\u0941\u0930\u0941\u0906\u0924\u0940 \u092e\u0940\u0932 \u0915\u0947 \u092a\u0924\u094d\u0925\u0930\u094b\u0902 \u092e\u0947\u0902 Watts, McKenna, Sharrock \u0914\u0930 Trezise \u0915\u093e \u092e\u0915\u0921\u093c\u0940-\u092d\u092f\u0917\u094d\u0930\u0938\u094d\u0924 \u0932\u094b\u0917\u094b\u0902 \u092e\u0947\u0902 \u0930\u0902\u0917-\u0928\u093e\u092e\u0915\u0930\u0923 \u092a\u0930 1986 \u0915\u093e \u0905\u0927\u094d\u092f\u092f\u0928 \u0936\u093e\u092e\u093f\u0932 \u0939\u0948, \u0914\u0930 1990 \u0915\u0947 \u0926\u0936\u0915 \u0924\u0915 \u092f\u0939 \u091a\u093f\u0902\u0924\u093e, \u092d\u092f, \u0906\u0918\u093e\u0924 (trauma) \u0914\u0930 \u0905\u0935\u0938\u093e\u0926 \u0915\u0947 \u0905\u0927\u094d\u092f\u092f\u0928 \u0915\u093e \u090f\u0915 \u092e\u093e\u0928\u0915 \u0914\u091c\u093c\u093e\u0930 \u092c\u0928 \u0917\u092f\u093e\u0964",creator:"\u092d\u093e\u0935\u0928\u093e\u0924\u094d\u092e\u0915 \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0915\u093e \u0915\u094b\u0908 \u090f\u0915 \u0906\u0935\u093f\u0937\u094d\u0915\u093e\u0930\u0915 \u0928\u0939\u0940\u0902 \u0939\u0948\u0964 \u092f\u0939 J. R. Stroop \u0915\u0947 \u092e\u0942\u0932 1935 \u0915\u0947 \u0930\u0902\u0917-\u0936\u092c\u094d\u0926 \u091f\u093e\u0938\u094d\u0915 \u0938\u0947 \u0909\u0924\u0930\u093e \u0939\u0948; \u092d\u093e\u0935\u0928\u093e\u0924\u094d\u092e\u0915 \u0930\u0942\u092a\u093e\u0902\u0924\u0930 \u0915\u094b 1980 \u0915\u0947 \u0926\u0936\u0915 \u092e\u0947\u0902 \u0915\u0908 \u091a\u093f\u0902\u0924\u093e-\u0936\u094b\u0927\u0915\u0930\u094d\u0924\u093e\u0913\u0902 \u0928\u0947 \u0935\u093f\u0915\u0938\u093f\u0924 \u0915\u093f\u092f\u093e, \u0914\u0930 \u091c\u093f\u0938 \u092a\u094d\u0930\u092d\u093e\u0935\u0936\u093e\u0932\u0940 \u0938\u092e\u0940\u0915\u094d\u0937\u093e \u0928\u0947 \u0907\u0938 \u0924\u0930\u0940\u0915\u093c\u0947 \u0915\u094b \u0928\u093e\u092e \u0926\u0947\u0915\u0930 \u090f\u0915 \u091c\u0917\u0939 \u0938\u092e\u0947\u091f\u093e, \u0935\u0939 \u0939\u0948 Williams, Mathews \u0914\u0930 MacLeod \u0915\u093e 1996 \u0915\u093e \u092a\u0930\u094d\u091a\u093e, \u091c\u094b Psychological Bulletin \u092e\u0947\u0902 \u091b\u092a\u093e\u0964",methods:"\u092c\u0938 \u090f\u0915 \u0939\u0940 \u091a\u0940\u091c\u093c \u092a\u0930 \u0928\u091c\u093c\u0930 \u091c\u092e\u093e\u090f\u0901 \u2014 \u0930\u0902\u0917 \u092a\u0930 \u2014 \u0914\u0930 \u0936\u092c\u094d\u0926 \u0915\u094b \u0910\u0938\u093e \u0926\u0943\u0936\u094d\u092f-\u0936\u094b\u0930 \u0938\u092e\u091d\u0947\u0902 \u091c\u093f\u0938\u0947 \u0906\u092a \u0915\u092d\u0940 \u092a\u0922\u093c\u0924\u0947 \u0939\u0940 \u0928\u0939\u0940\u0902\u0964 \u0939\u094b\u0921\u093c \u0932\u0917\u093e\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u090f\u0915 \u0938\u094d\u0925\u093f\u0930 \u0932\u092f \u092c\u0928\u093e\u090f \u0930\u0916\u0947\u0902, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u091c\u0932\u094d\u0926\u092c\u093e\u091c\u093c\u0940 \u092e\u0947\u0902 \u0906\u092a \u092d\u093e\u0930\u0940 \u0936\u092c\u094d\u0926\u094b\u0902 \u092a\u0930 \u0932\u0921\u093c\u0916\u0921\u093c\u093e\u0924\u0947 \u0939\u0948\u0902; \u0905\u0917\u0930 \u0905\u091f\u0915\u0947\u0902, \u0924\u094b \u090f\u0915 \u092a\u0932 \u0927\u0940\u092e\u0947 \u0939\u094b\u0915\u0930 \u092b\u093f\u0930 \u0938\u0947 \u0938\u094d\u092f\u093e\u0939\u0940 \u092a\u0930 \u0927\u094d\u092f\u093e\u0928 \u091f\u093f\u0915\u093e\u090f\u0901\u0964 \u092d\u093e\u0930\u0940 \u0914\u0930 \u0924\u091f\u0938\u094d\u0925 \u0936\u092c\u094d\u0926\u094b\u0902 \u0915\u094b \u092c\u094d\u0932\u0949\u0915\u094b\u0902 \u092e\u0947\u0902 \u092c\u093e\u0901\u091f\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u092c\u0947\u0924\u0930\u0924\u0940\u092c \u092e\u093f\u0932\u093e\u0915\u0930 \u0926\u0947\u0928\u093e \u0939\u0930 \u091f\u094d\u0930\u093e\u092f\u0932 \u092a\u0930 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0915\u0938\u093e \u0939\u0941\u0906 \u0928\u093f\u092f\u0902\u0924\u094d\u0930\u0923 \u0938\u093e\u0927\u0924\u093e \u0939\u0948\u0964",duration:"\u091b\u094b\u091f\u0947 \u0938\u0924\u094d\u0930 \u0938\u092c\u0938\u0947 \u0905\u091a\u094d\u091b\u0947 \u0930\u0939\u0924\u0947 \u0939\u0948\u0902 \u2014 \u0915\u093c\u0930\u0940\u092c 3 \u0938\u0947 5 \u092e\u093f\u0928\u091f, \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u0915\u0941\u091b \u092c\u093e\u0930\u0964 \u0926\u0916\u093c\u0932 \u0915\u0947 \u0916\u093c\u093f\u0932\u093e\u092b\u093c \u0927\u094d\u092f\u093e\u0928 \u091f\u093f\u0915\u093e\u0928\u093e \u0925\u0915\u093e \u0926\u0947\u0928\u0947 \u0935\u093e\u0932\u093e \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0909\u0938 \u092c\u093f\u0902\u0926\u0941 \u0938\u0947 \u092a\u0939\u0932\u0947 \u0930\u0941\u0915 \u091c\u093e\u090f\u0901 \u091c\u0939\u093e\u0901 \u0906\u092a \u092c\u0947\u0927\u094d\u092f\u093e\u0928\u0940 \u092e\u0947\u0902 \u0936\u092c\u094d\u0926 \u092a\u0922\u093c\u0928\u0947 \u0932\u0917\u0947\u0902, \u0914\u0930 \u0907\u0938\u0947 \u0918\u0902\u091f\u094b\u0902 \u0930\u0917\u0921\u093c\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u090f\u0915 \u0935\u093f\u0935\u093f\u0927 \u0926\u093f\u0928\u091a\u0930\u094d\u092f\u093e \u0915\u093e \u090f\u0915 \u0939\u093f\u0938\u094d\u0938\u093e \u0938\u092e\u091d\u0947\u0902\u0964",research:"\u091c\u094b \u092a\u0941\u0916\u093c\u094d\u0924\u093e \u0939\u0948 \u0935\u0939 \u0938\u0902\u0915\u0930\u093e \u0914\u0930 \u0905\u091a\u0930\u091c-\u0930\u0939\u093f\u0924 \u0939\u0948: \u091c\u092c \u0936\u092c\u094d\u0926 \u092d\u093e\u0935\u0928\u093e\u0924\u094d\u092e\u0915 \u0930\u0942\u092a \u0938\u0947 \u092d\u093e\u0930\u0940 \u0939\u094b, \u0924\u092c \u0932\u094b\u0917 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0922\u0902\u0917 \u0938\u0947 \u0930\u0902\u0917 \u0927\u0940\u0930\u0947 \u092c\u0924\u093e\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u092f\u0939 \u0927\u0940\u092e\u093e\u092a\u0928 \u0909\u0928 \u0936\u092c\u094d\u0926\u094b\u0902 \u0915\u0947 \u0932\u093f\u090f \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0939\u094b\u0924\u093e \u0939\u0948 \u091c\u094b \u0935\u094d\u092f\u0915\u094d\u0924\u093f \u0915\u0940 \u0905\u092a\u0928\u0940 \u091a\u093f\u0902\u0924\u093e \u0938\u0947 \u091c\u0941\u0921\u093c\u0947 \u0939\u094b\u0902 (\u091a\u093f\u0902\u0924\u093f\u0924 \u0932\u094b\u0917\u094b\u0902 \u0915\u0947 \u0932\u093f\u090f \u0916\u093c\u0924\u0930\u093e, \u0916\u093e\u0928-\u092a\u093e\u0928 \u0935\u093f\u0915\u093e\u0930 \u0915\u0947 \u0932\u093f\u090f \u0936\u0930\u0940\u0930 \u0938\u0947 \u091c\u0941\u0921\u093c\u0947 \u0936\u092c\u094d\u0926, \u0935\u0917\u0948\u0930\u0939) \u2014 \u0907\u0938\u0940\u0932\u093f\u090f \u092f\u0939 \u090f\u0915 \u0938\u092e\u094d\u092e\u093e\u0928\u093f\u0924 \u092e\u093e\u092a\u0928-\u0914\u091c\u093c\u093e\u0930 \u0939\u0948\u0964 \u091c\u094b \u0921\u0917\u092e\u0917 \u0939\u0948 \u0935\u0939 \u0907\u0938\u0915\u0947 \u092a\u0940\u091b\u0947 \u0915\u0940 \u0932\u094b\u0915\u092a\u094d\u0930\u093f\u092f \u0915\u0939\u093e\u0928\u0940 \u0939\u0948: \u0907\u0938 \u092a\u094d\u0930\u092d\u093e\u0935 \u0915\u093e \u092c\u0921\u093c\u093e \u0939\u093f\u0938\u094d\u0938\u093e \u090f\u0915 \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u0916\u093c\u0924\u0930\u093e-\u091c\u0928\u093f\u0924 \u0927\u0940\u092e\u0947\u092a\u0928 \u0914\u0930 \u091f\u094d\u0930\u093e\u092f\u0932\u094b\u0902 \u0915\u0947 \u092c\u0940\u091a \u0915\u0947 \u0905\u0938\u0930 \u0938\u0947 \u0938\u092e\u091d\u093e\u092f\u093e \u091c\u093e \u0938\u0915\u0924\u093e \u0939\u0948, \u0928 \u0915\u093f \u0915\u093f\u0938\u0940 \u0924\u0947\u091c\u093c, \u0938\u094d\u0935\u091a\u093e\u0932\u093f\u0924 \u0927\u094d\u092f\u093e\u0928-\u0916\u093f\u0902\u091a\u093e\u0935 \u0938\u0947; \u0922\u0915\u0947 \u0939\u0941\u090f \u092f\u093e \u0905\u0935\u091a\u0947\u0924\u0928 (subliminal) \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0920\u0940\u0915 \u0938\u0947 \u0926\u094b\u0939\u0930\u093e\u090f \u0928\u0939\u0940\u0902 \u091c\u093e \u092a\u093e\u0924\u0947, \u0914\u0930 70 \u0905\u0927\u094d\u092f\u092f\u0928\u094b\u0902 \u0915\u0947 \u090f\u0915 \u092e\u0947\u091f\u093e-\u0935\u093f\u0936\u094d\u0932\u0947\u0937\u0923 \u092e\u0947\u0902 \u0938\u092c\u0938\u0947 \u092c\u0921\u093c\u0947 \u092a\u094d\u0930\u092d\u093e\u0935 \u092c\u094d\u0932\u0949\u0915-\u0906\u0927\u093e\u0930\u093f\u0924 \u092a\u094d\u0930\u0938\u094d\u0924\u0941\u0924\u093f \u0938\u0947 \u0906\u090f\u0964 \u0907\u0938\u0915\u093e \u0915\u094b\u0908 \u0905\u091a\u094d\u091b\u093e \u0938\u092c\u0942\u0924 \u0928\u0939\u0940\u0902 \u0915\u093f \u0907\u0938\u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u0927\u094d\u092f\u093e\u0928 \u0915\u094b \u092a\u0948\u0928\u093e \u0915\u0930\u0924\u093e \u0939\u0948, \u092e\u0942\u0921 \u0938\u0941\u0927\u093e\u0930\u0924\u093e \u0939\u0948 \u092f\u093e \u0905\u0938\u0932 \u091c\u093c\u093f\u0902\u0926\u0917\u0940 \u0915\u0940 \u092d\u093e\u0935\u0928\u093e\u0924\u094d\u092e\u0915 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0918\u091f\u093e\u0924\u093e \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0907\u0938\u0947 \u0905\u092a\u0928\u0947 \u0927\u094d\u092f\u093e\u0928 \u0915\u094b \u091d\u093e\u0901\u0915\u0928\u0947 \u0915\u0940 \u0916\u093f\u0921\u093c\u0915\u0940 \u0938\u092e\u091d\u0947\u0902, \u0909\u0938\u0915\u093e \u0907\u0932\u093e\u091c \u0928\u0939\u0940\u0902\u0964",rec:"\u0907\u0938\u0947 \u090f\u0915 \u091b\u094b\u091f\u0947 \u0935\u093e\u0930\u094d\u092e-\u0905\u092a \u0915\u0947 \u0924\u094c\u0930 \u092a\u0930 \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0915\u0930\u0947\u0902 \u0924\u093e\u0915\u093f \u092e\u0939\u0938\u0942\u0938 \u0915\u0930 \u0938\u0915\u0947\u0902 \u0915\u093f \u092d\u093e\u0930\u0940 \u0936\u092c\u094d\u0926 \u0927\u094d\u092f\u093e\u0928 \u0915\u094b \u0915\u0948\u0938\u0947 \u0916\u0940\u0902\u091a\u0924\u0947 \u0939\u0948\u0902, \u092b\u093f\u0930 \u0906\u0917\u0947 \u092c\u0922\u093c \u091c\u093e\u090f\u0901; \u092f\u0939 \u0909\u092e\u094d\u092e\u0940\u0926 \u0928 \u0930\u0916\u0947\u0902 \u0915\u093f \u092f\u0939 \u0906\u092a\u0915\u094b \u0936\u093e\u0902\u0924 \u092f\u093e \u0906\u092e \u0924\u094c\u0930 \u092a\u0930 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0927\u094d\u092f\u093e\u0928\u092e\u0917\u094d\u0928 \u092c\u0928\u093e \u0926\u0947\u0917\u093e\u0964",faq:[["\u092e\u0948\u0902 \"\u0916\u093c\u0924\u0930\u093e\" \u091c\u0948\u0938\u0947 \u0936\u092c\u094d\u0926\u094b\u0902 \u092a\u0930 \u0927\u0940\u092e\u093e \u0915\u094d\u092f\u094b\u0902 \u0939\u094b \u091c\u093e\u0924\u093e \u0939\u0942\u0901, \u091c\u092c\u0915\u093f \u092e\u0948\u0902 \u0938\u093f\u0930\u094d\u092b\u093c \u0930\u0902\u0917 \u092c\u0924\u093e \u0930\u0939\u093e \u0939\u0942\u0901?","\u092d\u093e\u0930\u0940 \u0936\u092c\u094d\u0926, \u0907\u0938\u0938\u0947 \u092a\u0939\u0932\u0947 \u0915\u093f \u0906\u092a \u0909\u0928\u094d\u0939\u0947\u0902 \u0926\u092c\u093e \u092a\u093e\u090f\u0901, \u0927\u094d\u092f\u093e\u0928 \u0914\u0930 \u092a\u094d\u0930\u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0915\u093e \u090f\u0915 \u0939\u093f\u0938\u094d\u0938\u093e \u091d\u092a\u091f \u0932\u0947\u0924\u0947 \u0939\u0948\u0902, \u0907\u0938\u0932\u093f\u090f \u0930\u0902\u0917 \u0935\u093e\u0932\u0940 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0938\u0947\u0915\u0902\u0921 \u0915\u0947 \u090f\u0915 \u0905\u0902\u0936 \u0915\u0940 \u0926\u0947\u0930 \u0938\u0947 \u0906\u0924\u0940 \u0939\u0948\u0964 \u0935\u0939\u0940 \u0926\u0947\u0930\u0940 \u0907\u0938 \u091f\u093e\u0938\u094d\u0915 \u0915\u093e \u092a\u0942\u0930\u093e \u092e\u0915\u093c\u0938\u0926 \u0939\u0948, \u0906\u092a\u0915\u0940 \u0915\u094b\u0908 \u0917\u093c\u0932\u0924\u0940 \u0928\u0939\u0940\u0902\u0964"],["\u0915\u094d\u092f\u093e \u0907\u0938\u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u092e\u0941\u091d\u0947 \u0905\u0938\u0932 \u091c\u093c\u093f\u0902\u0926\u0917\u0940 \u092e\u0947\u0902 \u0924\u0928\u093e\u0935\u092d\u0930\u0947 \u0936\u092c\u094d\u0926\u094b\u0902 \u0915\u0947 \u092a\u094d\u0930\u0924\u093f \u0915\u092e \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e\u0936\u0940\u0932 \u092c\u0928\u093e \u0926\u0947\u0917\u093e?","\u0907\u0938\u0915\u093e \u0915\u094b\u0908 \u0905\u091a\u094d\u091b\u093e \u0938\u092c\u0942\u0924 \u0928\u0939\u0940\u0902 \u0939\u0948\u0964 \u092f\u0939 \u091f\u093e\u0938\u094d\u0915 \u092d\u093e\u0930\u0940 \u0936\u092c\u094d\u0926\u094b\u0902 \u092a\u0930 \u0927\u094d\u092f\u093e\u0928 \u0915\u094b \u092e\u093e\u092a\u0928\u0947 \u092e\u0947\u0902 \u0924\u094b \u092a\u0915\u094d\u0915\u093e \u0939\u0948, \u092a\u0930 \u0907\u0938\u0915\u0947 \u0905\u092d\u094d\u092f\u093e\u0938 \u0938\u0947 \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0940 \u092d\u093e\u0935\u0928\u093e\u0924\u094d\u092e\u0915 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0918\u091f\u0924\u0940 \u0939\u094b \u092f\u093e \u091f\u093e\u0938\u094d\u0915 \u0915\u0947 \u092c\u093e\u0939\u0930 \u0915\u094b\u0908 \u092b\u093c\u093e\u092f\u0926\u093e \u0939\u094b\u0924\u093e \u0939\u094b, \u092f\u0939 \u0928\u0939\u0940\u0902 \u0926\u093f\u0916\u093e \u0939\u0948\u0964"],["\u0915\u094d\u092f\u093e \u090f\u0915 \u092c\u0921\u093c\u093e emotional Stroop \u092a\u094d\u0930\u092d\u093e\u0935 \u0907\u0938 \u092c\u093e\u0924 \u0915\u093e \u0938\u0902\u0915\u0947\u0924 \u0939\u0948 \u0915\u093f \u092e\u0941\u091d\u092e\u0947\u0902 \u0915\u0941\u091b \u0917\u0921\u093c\u092c\u0921\u093c \u0939\u0948?","\u0928\u0939\u0940\u0902\u0964 \u0915\u0941\u091b \u0916\u093c\u093e\u0938 \u0925\u0940\u092e\u094b\u0902 \u092a\u0930 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0927\u0940\u092e\u093e\u092a\u0928 \u0915\u0941\u091b \u091a\u093f\u0902\u0924\u093e, \u092d\u092f \u0914\u0930 \u0906\u0918\u093e\u0924 \u0915\u0940 \u0938\u094d\u0925\u093f\u0924\u093f\u092f\u094b\u0902 \u092e\u0947\u0902 \u0926\u093f\u0916\u0924\u093e \u0939\u0948, \u092a\u0930 \u092f\u0939 \u0915\u0908 \u0938\u092e\u0942\u0939\u094b\u0902 \u092e\u0947\u0902 \u090f\u0915 \u0936\u094b\u0927-\u0914\u0930-\u0938\u094d\u0915\u094d\u0930\u0940\u0928\u093f\u0902\u0917 \u0938\u0902\u0915\u0947\u0924 \u0939\u0948, \u0938\u094d\u0935-\u0928\u093f\u0926\u093e\u0928 \u0928\u0939\u0940\u0902 \u2014 \u0914\u0930 \u0907\u0938\u092e\u0947\u0902 \u0915\u093e\u092b\u093c\u0940 \u092b\u093c\u0930\u094d\u0915\u093c \u092c\u0938 \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u0939\u0940 \u0939\u094b\u0924\u093e \u0939\u0948\u0964"]],variants:"\u0906\u092e \u0930\u0942\u092a\u093e\u0902\u0924\u0930\u094b\u0902 \u092e\u0947\u0902 \u0936\u092c\u094d\u0926-\u0938\u092e\u0942\u0939 \u0915\u094b \u0915\u093f\u0938\u0940 \u0916\u093c\u093e\u0938 \u0925\u0940\u092e \u092a\u0930 \u092c\u0926\u0932 \u0926\u093f\u092f\u093e \u091c\u093e\u0924\u093e \u0939\u0948 (\u0916\u093c\u0924\u0930\u093e, \u0938\u093e\u092e\u093e\u091c\u093f\u0915, \u0936\u0930\u0940\u0930-\u091b\u0935\u093f, \u0906\u0918\u093e\u0924-\u0938\u0902\u092c\u0902\u0927\u0940, \u092f\u093e \u0928\u0936\u0947 \u0915\u0947 \u0938\u0902\u0915\u0947\u0924), \u0936\u092c\u094d\u0926\u094b\u0902 \u0915\u094b \u090f\u0915 \u0939\u0940 \u092a\u094d\u0930\u0915\u093e\u0930 \u0915\u0947 \u092c\u094d\u0932\u0949\u0915\u094b\u0902 \u092c\u0928\u093e\u092e \u092c\u0947\u0924\u0930\u0924\u0940\u092c \u092e\u093f\u0932\u093e\u0915\u0930 \u0926\u093f\u0916\u093e\u092f\u093e \u091c\u093e\u0924\u093e \u0939\u0948, \u0936\u092c\u094d\u0926\u094b\u0902 \u0915\u094b \u092c\u0939\u0941\u0924 \u0925\u094b\u0921\u093c\u0940 \u0926\u0947\u0930 \u0915\u0947 \u0932\u093f\u090f \u092f\u093e \u0922\u0915\u0915\u0930 \u091a\u092e\u0915\u093e\u092f\u093e \u091c\u093e\u0924\u093e \u0939\u0948 \u0924\u093e\u0915\u093f \u0938\u094d\u0935\u091a\u093e\u0932\u093f\u0924 \u092a\u094d\u0930\u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0915\u0940 \u091c\u093e\u0901\u091a \u0939\u094b, \u092f\u093e \u0936\u092c\u094d\u0926\u094b\u0902 \u0915\u0940 \u091c\u0917\u0939 \u092d\u093e\u0935\u0928\u093e\u0924\u094d\u092e\u0915 \u091a\u0947\u0939\u0930\u0947 \u092f\u093e \u0924\u0938\u094d\u0935\u0940\u0930\u0947\u0902 \u0930\u0916\u0915\u0930 \u090f\u0915 \u091a\u093f\u0924\u094d\u0930-\u0936\u092c\u094d\u0926 \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u092c\u0928\u093e\u092f\u093e \u091c\u093e\u0924\u093e \u0939\u0948\u0964"},zh:{about:"\u60c5\u7eea Stroop \u4f1a\u5411\u4f60\u5448\u73b0\u7528\u4e0d\u540c\u58a8\u6c34\u989c\u8272\u5370\u51fa\u7684\u8bcd\uff0c\u800c\u4f60\u552f\u4e00\u7684\u4efb\u52a1\u662f\u5c3d\u5feb\u8bf4\u51fa\u989c\u8272\uff0c\u540c\u65f6\u65e0\u89c6\u8fd9\u4e2a\u8bcd\u7684\u542b\u4e49\u3002\u96be\u70b9\u5728\u4e8e\uff0c\u6709\u4e9b\u8bcd\u5e26\u6709\u5f3a\u70c8\u7684\u60c5\u7eea\u8272\u5f69\uff08\u201c\u5371\u9669\u201d\u201c\u5931\u8d25\u201d\u201c\u6b7b\u4ea1\u201d\uff09\uff0c\u6709\u4e9b\u5219\u662f\u4e2d\u6027\u7684\uff08\u201c\u684c\u5b50\u201d\u201c\u7a97\u6237\u201d\uff09\uff0c\u5373\u4fbf\u8bcd\u4e49\u4e0e\u4efb\u52a1\u65e0\u5173\uff0c\u5927\u591a\u6570\u4eba\u5728\u5e26\u60c5\u7eea\u8272\u5f69\u7684\u8bcd\u4e0a\u4ecd\u4f1a\u660e\u663e\u53d8\u6162\u3002",benefit:"\u5b83\u8bad\u7ec3\u5728\u5e72\u6270\u4e0b\u7684\u9009\u62e9\u6027\u6ce8\u610f\u548c\u53cd\u5e94\u63a7\u5236\uff0c\u5177\u4f53\u6765\u8bf4\uff0c\u5c31\u662f\u5728\u4e00\u4e2a\u60c5\u7eea\u4e0a\u5f88\u201c\u5435\u201d\u7684\u5e72\u6270\u8bcd\u4e89\u593a\u4f60\u7684\u6ce8\u610f\u65f6\uff0c\u4ecd\u80fd\u628a\u4e00\u9879\u7b80\u5355\u4efb\u52a1\u505a\u4e0b\u53bb\u7684\u80fd\u529b\u3002\u5b83\u8fd8\u8ba9\u4f60\u5207\u8eab\u4f53\u4f1a\u5230\uff0c\u5e26\u60c5\u7eea\u8272\u5f69\u7684\u8bed\u8a00\u662f\u5982\u4f55\u628a\u6ce8\u610f\u529b\u4ece\u624b\u5934\u7684\u4e8b\u60c5\u4e0a\u62fd\u8d70\u7684\u3002",history:"\u5b83\u76f4\u63a5\u8131\u80ce\u4e8e\u7ecf\u5178\u7684\u989c\u8272-\u8bcd Stroop \u4efb\u52a1\uff0c\u53ea\u662f\u628a\u989c\u8272\u8bcd\u6362\u6210\u4e86\u5e26\u60c5\u7eea\u610f\u4e49\u7684\u8bcd\u3002\u8fd9\u4e00\u601d\u8def\u5728 1980 \u5e74\u4ee3\u7684\u4e34\u5e8a\u5fc3\u7406\u5b66\u4e2d\u5174\u8d77\uff0cWatts\u3001McKenna\u3001Sharrock \u548c Trezise 1986 \u5e74\u5173\u4e8e\u8718\u86db\u6050\u60e7\u8005\u989c\u8272\u547d\u540d\u7684\u7814\u7a76\u662f\u65e9\u671f\u91cc\u7a0b\u7891\u4e4b\u4e00\uff1b\u5230 1990 \u5e74\u4ee3\uff0c\u5b83\u6210\u4e3a\u7814\u7a76\u7126\u8651\u3001\u6050\u60e7\u75c7\u3001\u521b\u4f24\u548c\u6291\u90c1\u7684\u6807\u51c6\u5de5\u5177\u3002",creator:"\u60c5\u7eea\u7248\u672c\u6ca1\u6709\u5355\u4e00\u7684\u53d1\u660e\u8005\u3002\u5b83\u6e90\u81ea J. R. Stroop 1935 \u5e74\u6700\u521d\u7684\u989c\u8272-\u8bcd\u4efb\u52a1\uff1b\u60c5\u7eea\u5316\u7684\u6539\u7f16\u7531 1980 \u5e74\u4ee3\u7684\u51e0\u4f4d\u7126\u8651\u7814\u7a76\u8005\u53d1\u5c55\u800c\u6765\uff0c\u800c\u771f\u6b63\u4e3a\u8fd9\u4e00\u65b9\u6cd5\u547d\u540d\u5e76\u5c06\u5176\u6574\u5408\u8d77\u6765\u7684\u3001\u5f71\u54cd\u6df1\u8fdc\u7684\u7efc\u8ff0\uff0c\u662f Williams\u3001Mathews \u548c MacLeod 1996 \u5e74\u53d1\u8868\u5728\u300aPsychological Bulletin\u300b\u4e0a\u7684\u8bba\u6587\u3002",methods:"\u53ea\u9501\u5b9a\u4e00\u4ef6\u4e8b\u2014\u2014\u989c\u8272\uff0c\u628a\u8bcd\u5f53\u4f5c\u4f60\u4ece\u4e0d\u53bb\u8bfb\u7684\u89c6\u89c9\u566a\u58f0\u3002\u4fdd\u6301\u5e73\u7a33\u7684\u8282\u594f\u800c\u4e0d\u662f\u62a2\u7740\u6c42\u5feb\uff0c\u56e0\u4e3a\u6c42\u5feb\u4f1a\u8ba9\u4f60\u5728\u5e26\u60c5\u7eea\u8272\u5f69\u7684\u8bcd\u4e0a\u683d\u8ddf\u5934\uff1b\u4e00\u65e6\u7eca\u4f4f\uff0c\u5c31\u6162\u4e0b\u6765\u4e00\u62cd\uff0c\u91cd\u65b0\u628a\u6ce8\u610f\u529b\u951a\u5b9a\u5728\u58a8\u8272\u4e0a\u3002\u628a\u5e26\u60c5\u7eea\u8272\u5f69\u7684\u8bcd\u548c\u4e2d\u6027\u8bcd\u968f\u673a\u6df7\u5728\u4e00\u8d77\uff0c\u6bd4\u628a\u5b83\u4eec\u6210\u5757\u5206\u7ec4\uff0c\u66f4\u80fd\u8bad\u7ec3\u9010\u8bd5\u6b21\u7684\u7cbe\u7ec6\u63a7\u5236\u3002",duration:"\u77ed\u65f6\u6bb5\u6548\u679c\u6700\u597d\uff0c\u5927\u7ea6\u6bcf\u6b21 3 \u5230 5 \u5206\u949f\u3001\u6bcf\u5468\u51e0\u6b21\u3002\u5728\u5e72\u6270\u4e0b\u4fdd\u6301\u4e13\u6ce8\u5f88\u8d39\u795e\uff0c\u6240\u4ee5\u8981\u5728\u4f60\u5f00\u59cb\u4e0b\u610f\u8bc6\u5730\u8bfb\u8bcd\u4e4b\u524d\u505c\u4e0b\u6765\uff0c\u5e76\u628a\u5b83\u5f53\u4f5c\u591a\u6837\u5316\u65e5\u5e38\u4e2d\u7684\u4e00\u9879\uff0c\u800c\u4e0d\u662f\u8981\u78e8\u4e0a\u4e00\u5c0f\u65f6\u7684\u4e1c\u897f\u3002",research:"\u624e\u5b9e\u7684\u7ed3\u8bba\u65e2\u7a84\u53c8\u4e0d\u51fa\u610f\u6599\uff1a\u5f53\u8bcd\u5e26\u60c5\u7eea\u8272\u5f69\u65f6\uff0c\u4eba\u4eec\u8bf4\u51fa\u989c\u8272\u7684\u901f\u5ea6\u53ef\u9760\u5730\u66f4\u6162\uff0c\u800c\u4e14\u5bf9\u4e8e\u90a3\u4e9b\u4e0e\u67d0\u4eba\u81ea\u8eab\u5173\u5207\u76f8\u5173\u7684\u8bcd\uff08\u7126\u8651\u8005\u9762\u5bf9\u5a01\u80c1\u8bcd\u3001\u8fdb\u98df\u969c\u788d\u8005\u9762\u5bf9\u8eab\u4f53\u76f8\u5173\u8bcd\uff0c\u7b49\u7b49\uff09\uff0c\u8fd9\u79cd\u53d8\u6162\u66f4\u660e\u663e\uff0c\u6b63\u56e0\u5982\u6b64\u5b83\u662f\u4e00\u4e2a\u53d7\u8ba4\u53ef\u7684\u6d4b\u91cf\u5de5\u5177\u3002\u4e0d\u9760\u8c31\u7684\uff0c\u662f\u5b83\u80cc\u540e\u90a3\u4e2a\u6d41\u884c\u7684\u6545\u4e8b\uff1a\u56e0\u4e3a\u4e00\u79cd\u7b3c\u7edf\u7684\u3001\u7531\u5a01\u80c1\u9a71\u52a8\u7684\u53d8\u6162\uff0c\u52a0\u4e0a\u8bd5\u6b21\u4e4b\u95f4\u7684\u5ef6\u7eed\u6548\u5e94\uff0c\u5c31\u80fd\u89e3\u91ca\u5927\u90e8\u5206\u6548\u5e94\uff0c\u800c\u975e\u4ec0\u4e48\u5feb\u901f\u3001\u81ea\u52a8\u7684\u6ce8\u610f\u652b\u53d6\uff1b\u5176\u906e\u853d\u6216\u9608\u4e0b\u7248\u672c\u96be\u4ee5\u91cd\u590d\uff1b\u800c\u5728\u4e00\u9879\u5bf9 70 \u9879\u7814\u7a76\u7684\u5143\u5206\u6790\u4e2d\uff0c\u6700\u5927\u7684\u6548\u5e94\u6765\u81ea\u6210\u5757\u5448\u73b0\u3002\u6ca1\u6709\u53ef\u9760\u8bc1\u636e\u8868\u660e\u7ec3\u4e60\u5b83\u80fd\u78e8\u5229\u4e00\u822c\u6ce8\u610f\u529b\u3001\u63d0\u5347\u60c5\u7eea\uff0c\u6216\u964d\u4f4e\u73b0\u5b9e\u4e2d\u7684\u60c5\u7eea\u53cd\u5e94\u6027\uff0c\u6240\u4ee5\u628a\u5b83\u5f53\u4f5c\u7aa5\u63a2\u4f60\u81ea\u8eab\u6ce8\u610f\u7684\u4e00\u6247\u7a97\uff0c\u800c\u4e0d\u662f\u4fee\u590d\u5b83\u7684\u5de5\u5177\u3002",rec:"\u628a\u5b83\u5f53\u4f5c\u4e00\u4e2a\u7b80\u77ed\u7684\u70ed\u8eab\uff0c\u53bb\u611f\u53d7\u5e26\u60c5\u7eea\u8272\u5f69\u7684\u8bcd\u5982\u4f55\u62d6\u7d2f\u4e13\u6ce8\uff0c\u7136\u540e\u5c31\u7ffb\u7bc7\uff1b\u522b\u6307\u671b\u5b83\u80fd\u8ba9\u4f60\u66f4\u5e73\u9759\uff0c\u6216\u6574\u4f53\u4e0a\u66f4\u4e13\u6ce8\u3002",faq:[["\u6211\u53ea\u662f\u5728\u8bf4\u989c\u8272\uff0c\u4e3a\u4ec0\u4e48\u5728\u201c\u5371\u9669\u201d\u8fd9\u7c7b\u8bcd\u4e0a\u8fd8\u662f\u66f4\u6162\uff1f","\u5e26\u60c5\u7eea\u8272\u5f69\u7684\u8bcd\u4f1a\u5728\u4f60\u6765\u5f97\u53ca\u538b\u5236\u5b83\u4eec\u4e4b\u524d\u62a2\u8d70\u4e00\u90e8\u5206\u6ce8\u610f\u548c\u52a0\u5de5\u8d44\u6e90\uff0c\u4e8e\u662f\u989c\u8272\u53cd\u5e94\u5c31\u665a\u4e86\u96f6\u70b9\u51e0\u79d2\u3002\u90a3\u6bb5\u5ef6\u8fdf\u6b63\u662f\u8fd9\u9879\u4efb\u52a1\u7684\u5168\u90e8\u610f\u4e49\u6240\u5728\uff0c\u800c\u4e0d\u662f\u4f60\u8fd9\u8fb9\u51fa\u4e86\u4ec0\u4e48\u9519\u3002"],["\u7ec3\u8fd9\u4e2a\u4f1a\u8ba9\u6211\u5728\u73b0\u5b9e\u751f\u6d3b\u4e2d\u5bf9\u538b\u529b\u8bcd\u7684\u53cd\u5e94\u53d8\u5c0f\u5417\uff1f","\u6ca1\u6709\u53ef\u9760\u8bc1\u636e\u652f\u6301\u8fd9\u4e00\u70b9\u3002\u8fd9\u9879\u4efb\u52a1\u5728\u6d4b\u91cf\u5bf9\u5e26\u60c5\u7eea\u8272\u5f69\u8bcd\u7684\u6ce8\u610f\u4e0a\u5f88\u624e\u5b9e\uff0c\u4f46\u7ec3\u4e60\u5b83\u5e76\u672a\u88ab\u8bc1\u660e\u80fd\u964d\u4f4e\u65e5\u5e38\u7684\u60c5\u7eea\u53cd\u5e94\u6027\uff0c\u6216\u8fc1\u79fb\u5230\u4efb\u52a1\u672c\u8eab\u4e4b\u5916\u3002"],["\u60c5\u7eea Stroop \u6548\u5e94\u5927\uff0c\u662f\u4e0d\u662f\u8bf4\u660e\u6211\u6709\u4ec0\u4e48\u95ee\u9898\uff1f","\u4e0d\u662f\u3002\u5728\u67d0\u4e9b\u7126\u8651\u3001\u6050\u60e7\u75c7\u548c\u521b\u4f24\u7684\u8868\u73b0\u4e2d\uff0c\u5bf9\u7279\u5b9a\u4e3b\u9898\u7684\u53d8\u6162\u4f1a\u66f4\u660e\u663e\uff0c\u4f46\u5b83\u662f\u8de8\u4eba\u7fa4\u7684\u7814\u7a76\u4e0e\u7b5b\u67e5\u4fe1\u53f7\uff0c\u800c\u4e0d\u662f\u81ea\u6211\u8bca\u65ad\u7684\u4f9d\u636e\uff0c\u800c\u4e14\u5927\u91cf\u7684\u4e2a\u4f53\u5dee\u5f02\u672c\u5c31\u5c5e\u4e8e\u6b63\u5e38\u8303\u56f4\u3002"]],variants:"\u5e38\u89c1\u7684\u53d8\u5316\u5305\u62ec\uff1a\u628a\u8bcd\u8868\u6362\u6210\u67d0\u4e2a\u7279\u5b9a\u4e3b\u9898\uff08\u5a01\u80c1\u3001\u793e\u4ea4\u3001\u8eab\u4f53\u5f62\u8c61\u3001\u521b\u4f24\u76f8\u5173\u6216\u6210\u763e\u7ebf\u7d22\uff09\uff1b\u628a\u8bcd\u6210\u5757\u6309\u5355\u4e00\u7c7b\u578b\u5448\u73b0\u800c\u975e\u968f\u673a\u6df7\u5408\uff1b\u5c06\u8bcd\u6781\u77ed\u6682\u5730\u95ea\u73b0\u6216\u52a0\u4ee5\u906e\u853d\uff0c\u4ee5\u63a2\u67e5\u81ea\u52a8\u52a0\u5de5\uff1b\u6216\u5728\u56fe-\u8bcd\u7248\u672c\u91cc\u7528\u60c5\u7eea\u9762\u5b54\u6216\u56fe\u7247\u6765\u66ff\u4ee3\u8bcd\u3002"}},sudoku:{ru:{about:"\u041b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u0430\u044f \u0433\u043e\u043b\u043e\u0432\u043e\u043b\u043e\u043c\u043a\u0430 \u043d\u0430 \u0441\u0435\u0442\u043a\u0435 6\xd76 \u2014 \u043c\u044f\u0433\u043a\u0438\u0439 \u0432\u0430\u0440\u0438\u0430\u043d\u0442 \u043a\u043b\u0430\u0441\u0441\u0438\u0447\u0435\u0441\u043a\u043e\u0439 9\xd79. \u0417\u0430\u043f\u043e\u043b\u043d\u0438 \u043a\u0430\u0436\u0434\u0443\u044e \u0441\u0442\u0440\u043e\u043a\u0443, \u0441\u0442\u043e\u043b\u0431\u0435\u0446 \u0438 \u0431\u043b\u043e\u043a \u0442\u0430\u043a, \u0447\u0442\u043e\u0431\u044b \u0446\u0438\u0444\u0440\u0430 \u0432\u0441\u0442\u0440\u0435\u0447\u0430\u043b\u0430\u0441\u044c \u0440\u043e\u0432\u043d\u043e \u043e\u0434\u0438\u043d \u0440\u0430\u0437. \u0411\u0435\u0437 \u0430\u0440\u0438\u0444\u043c\u0435\u0442\u0438\u043a\u0438, \u0447\u0438\u0441\u0442\u0430\u044f \u0434\u0435\u0434\u0443\u043a\u0446\u0438\u044f.",benefit:"\u0421\u0438\u0441\u0442\u0435\u043c\u043d\u043e\u0435 \u043b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u043e\u0435 \u043c\u044b\u0448\u043b\u0435\u043d\u0438\u0435, \u0440\u0430\u0431\u043e\u0447\u0443\u044e \u043f\u0430\u043c\u044f\u0442\u044c (\u0434\u0435\u0440\u0436\u0430\u0442\u044c \u0432 \u0433\u043e\u043b\u043e\u0432\u0435 \u043a\u0430\u043d\u0434\u0438\u0434\u0430\u0442\u043e\u0432), \u0442\u0435\u0440\u043f\u0435\u043d\u0438\u0435 \u0438 \u043f\u0440\u0438\u0432\u044b\u0447\u043a\u0443 \u043f\u0440\u043e\u0432\u0435\u0440\u044f\u0442\u044c \u0433\u0438\u043f\u043e\u0442\u0435\u0437\u0443 \u0434\u043e \u0445\u043e\u0434\u0430.",history:"\u041f\u0440\u0435\u0434\u043e\u043a \u2014 \u043b\u0430\u0442\u0438\u043d\u0441\u043a\u0438\u0439 \u043a\u0432\u0430\u0434\u0440\u0430\u0442, \u0438\u0437\u0443\u0447\u0435\u043d\u043d\u044b\u0439 \u041b\u0435\u043e\u043d\u0430\u0440\u0434\u043e\u043c \u042d\u0439\u043b\u0435\u0440\u043e\u043c \u0432 XVIII \u0432\u0435\u043a\u0435. \u0421\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u0430\u044f \u0433\u043e\u043b\u043e\u0432\u043e\u043b\u043e\u043c\u043a\u0430 \u0432\u044b\u0448\u043b\u0430 \u043a\u0430\u043a \xabNumber Place\xbb \u0432 \u0436\u0443\u0440\u043d\u0430\u043b\u0435 Dell \u0432 1979-\u043c, \u043f\u0435\u0440\u0435\u0438\u043c\u0435\u043d\u043e\u0432\u0430\u043d\u0430 \u0438 \u043f\u043e\u043f\u0443\u043b\u044f\u0440\u0438\u0437\u043e\u0432\u0430\u043d\u0430 \u0432 \u042f\u043f\u043e\u043d\u0438\u0438 \u043a\u043e\u043c\u043f\u0430\u043d\u0438\u0435\u0439 Nikoli \u0432 1984-\u043c, \u0441\u0442\u0430\u043b\u0430 \u0432\u0441\u0435\u043c\u0438\u0440\u043d\u043e\u0439 \u0432 2004\u20132005.",creator:"\u0421\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u0443\u044e \u0444\u043e\u0440\u043c\u0443 \u043f\u0440\u0438\u043f\u0438\u0441\u044b\u0432\u0430\u044e\u0442 \u0413\u043e\u0432\u0430\u0440\u0434\u0443 \u0413\u0430\u0440\u043d\u0441\u0443, \u0430\u043c\u0435\u0440\u0438\u043a\u0430\u043d\u0441\u043a\u043e\u043c\u0443 \u0430\u0440\u0445\u0438\u0442\u0435\u043a\u0442\u043e\u0440\u0443 \u043d\u0430 \u043f\u0435\u043d\u0441\u0438\u0438, \u043e\u043f\u0443\u0431\u043b\u0438\u043a\u043e\u0432\u0430\u0432\u0448\u0435\u043c\u0443 \u0435\u0451 \u0430\u043d\u043e\u043d\u0438\u043c\u043d\u043e \u0432 1979-\u043c. \u041d\u0435\u0441\u043c\u043e\u0442\u0440\u044f \u043d\u0430 \u044f\u043f\u043e\u043d\u0441\u043a\u043e\u0435 \u043d\u0430\u0437\u0432\u0430\u043d\u0438\u0435, \u0438\u0437\u043e\u0431\u0440\u0435\u0442\u0435\u043d\u0430 \u043d\u0435 \u0432 \u042f\u043f\u043e\u043d\u0438\u0438 \u2014 Nikoli \u043f\u043e\u043f\u0443\u043b\u044f\u0440\u0438\u0437\u0438\u0440\u043e\u0432\u0430\u043b\u0430, \u0430 \u0432\u0441\u0435\u043c\u0438\u0440\u043d\u044b\u0439 \u0431\u0443\u043c 2004-\u0433\u043e \u0437\u0430\u043f\u0443\u0441\u0442\u0438\u043b \u0433\u0435\u043d\u0435\u0440\u0430\u0442\u043e\u0440 \u0423\u044d\u0439\u043d\u0430 \u0413\u0443\u043b\u0434\u0430.",methods:"\u041d\u0430\u0447\u0438\u043d\u0430\u0439 \u0441 \u0441\u0430\u043c\u043e\u0439 \u043e\u0433\u0440\u0430\u043d\u0438\u0447\u0435\u043d\u043d\u043e\u0439 \u043a\u043b\u0435\u0442\u043a\u0438 \u2014 \u0441\u0442\u0440\u043e\u043a\u0438, \u0441\u0442\u043e\u043b\u0431\u0446\u0430 \u0438\u043b\u0438 \u0431\u043b\u043e\u043a\u0430 \u0441 \u043d\u0430\u0438\u043c\u0435\u043d\u044c\u0448\u0438\u043c \u0447\u0438\u0441\u043b\u043e\u043c \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u043e\u0432. \u041f\u043e\u043c\u0435\u0447\u0430\u0439 \u043a\u0430\u043d\u0434\u0438\u0434\u0430\u0442\u043e\u0432, \u043e\u0442\u0441\u0435\u043a\u0430\u0439 \u0441\u043a\u0430\u043d\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u0435\u043c \u0438 \u043d\u0435 \u0443\u0433\u0430\u0434\u044b\u0432\u0430\u0439: \u043d\u0430 6\xd76 \u043a\u0430\u0436\u0434\u044b\u0439 \u0445\u043e\u0434 \u0434\u043e\u043b\u0436\u0435\u043d \u0431\u044b\u0442\u044c \u0432\u044b\u043d\u0443\u0436\u0434\u0435\u043d \u043b\u043e\u0433\u0438\u043a\u043e\u0439.",duration:"\u041d\u0435\u0442 \xab\u0434\u043d\u0435\u0432\u043d\u043e\u0439 \u0434\u043e\u0437\u044b\xbb, \u043a\u043e\u0442\u043e\u0440\u0430\u044f \xab\u043f\u0435\u0440\u0435\u043f\u0440\u043e\u0448\u044c\u0451\u0442\xbb \u043c\u043e\u0437\u0433 \u2014 \u043e\u0442\u043d\u043e\u0441\u0438\u0441\u044c \u043a\u0430\u043a \u043a \u043f\u0440\u0438\u044f\u0442\u043d\u043e\u0439 \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0435 \u043b\u043e\u0433\u0438\u043a\u0438. 1\u20132 \u0433\u043e\u043b\u043e\u0432\u043e\u043b\u043e\u043c\u043a\u0438 \u0432 \u043f\u0435\u0440\u0435\u0440\u044b\u0432 \u2014 \u0434\u043e\u0441\u0442\u0430\u0442\u043e\u0447\u043d\u043e.",research:"\u0427\u0435\u0441\u0442\u043d\u043e: \u0433\u043e\u043b\u043e\u0432\u043e\u043b\u043e\u043c\u043a\u0438 \u0432\u0440\u043e\u0434\u0435 \u0441\u0443\u0434\u043e\u043a\u0443 \u043d\u0430\u0434\u0451\u0436\u043d\u043e \u0443\u043b\u0443\u0447\u0448\u0430\u044e\u0442 \u043d\u0430\u0432\u044b\u043a \u0440\u0435\u0448\u0430\u0442\u044c \u0441\u0443\u0434\u043e\u043a\u0443. \u041a\u0440\u0443\u043f\u043d\u044b\u0435 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u044f \u0441\u0432\u044f\u0437\u044b\u0432\u0430\u044e\u0442 \u0440\u0435\u0433\u0443\u043b\u044f\u0440\u043d\u044b\u0435 \u0433\u043e\u043b\u043e\u0432\u043e\u043b\u043e\u043c\u043a\u0438 \u0441 \u0431\u043e\u043b\u0435\u0435 \u043e\u0441\u0442\u0440\u044b\u043c \u043c\u044b\u0448\u043b\u0435\u043d\u0438\u0435\u043c \u0443 \u043f\u043e\u0436\u0438\u043b\u044b\u0445, \u043d\u043e \u043f\u0440\u0438\u0447\u0438\u043d\u043d\u043e\u0441\u0442\u044c \u043d\u0435 \u0434\u043e\u043a\u0430\u0437\u0430\u043d\u0430 \u2014 \u0432\u043e\u0437\u043c\u043e\u0436\u043d\u043e, \u043e\u0441\u0442\u0440\u044b\u0439 \u0443\u043c \u043f\u0440\u043e\u0441\u0442\u043e \u0447\u0430\u0449\u0435 \u0440\u0435\u0448\u0430\u0435\u0442 \u0433\u043e\u043b\u043e\u0432\u043e\u043b\u043e\u043c\u043a\u0438. \u041d\u0435 \u0436\u0434\u0438 \u0437\u0430\u0449\u0438\u0442\u044b \u043e\u0442 \u043a\u043e\u0433\u043d\u0438\u0442\u0438\u0432\u043d\u043e\u0433\u043e \u0441\u043f\u0430\u0434\u0430.",rec:"\u0418\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0439, \u0447\u0442\u043e\u0431\u044b \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u0442\u0435\u0440\u043f\u0435\u043b\u0438\u0432\u0443\u044e \u0431\u0435\u0437\u043e\u0448\u0438\u0431\u043e\u0447\u043d\u0443\u044e \u0434\u0435\u0434\u0443\u043a\u0446\u0438\u044e. \u041f\u0435\u0440\u0435\u0445\u043e\u0434\u0438 \u043d\u0430 9\xd79 \u0438 \u0441\u043b\u043e\u0436\u043d\u044b\u0435 \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u044b, \u043a\u043e\u0433\u0434\u0430 6\xd76 \u0441\u0442\u0430\u043d\u0435\u0442 \u0430\u0432\u0442\u043e\u043c\u0430\u0442\u0438\u0447\u0435\u0441\u043a\u0438\u043c.",faq:[["\u0421\u0443\u0434\u043e\u043a\u0443 \u2014 \u044f\u043f\u043e\u043d\u0441\u043a\u0430\u044f?","\u041d\u0430\u0437\u0432\u0430\u043d\u0438\u0435 \u0434\u0430, \u0433\u043e\u043b\u043e\u0432\u043e\u043b\u043e\u043c\u043a\u0430 \u043d\u0435\u0442. \u0421\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u0430\u044f \u0444\u043e\u0440\u043c\u0430 \u0441\u043e\u0437\u0434\u0430\u043d\u0430 \u0432 \u0421\u0428\u0410 \u0432 1979-\u043c \u2014 \u044f\u043f\u043e\u043d\u0441\u043a\u0430\u044f Nikoli \u043f\u043e\u043f\u0443\u043b\u044f\u0440\u0438\u0437\u0438\u0440\u043e\u0432\u0430\u043b\u0430 \u0438 \u043f\u0435\u0440\u0435\u0438\u043c\u0435\u043d\u043e\u0432\u0430\u043b\u0430."],["\u041d\u0443\u0436\u043d\u0430 \u043c\u0430\u0442\u0435\u043c\u0430\u0442\u0438\u043a\u0430?","\u041d\u0435\u0442. \u0426\u0438\u0444\u0440\u044b \u2014 \u043f\u0440\u043e\u0441\u0442\u043e \u0441\u0438\u043c\u0432\u043e\u043b\u044b; \u044d\u0442\u043e \u0447\u0438\u0441\u0442\u0430\u044f \u043b\u043e\u0433\u0438\u043a\u0430, \u043d\u0438\u043a\u0430\u043a\u043e\u0439 \u0430\u0440\u0438\u0444\u043c\u0435\u0442\u0438\u043a\u0438."],["\u0414\u0435\u043b\u0430\u0435\u0442 \u0443\u043c\u043d\u0435\u0435?","\u0414\u0435\u043b\u0430\u0435\u0442 \u043b\u0443\u0447\u0448\u0435 \u0432 \u043b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u0438\u0445 \u0433\u043e\u043b\u043e\u0432\u043e\u043b\u043e\u043c\u043a\u0430\u0445. \u0428\u0438\u0440\u043e\u043a\u0438\u0435 \u0437\u0430\u044f\u0432\u043b\u0435\u043d\u0438\u044f \u043f\u0440\u043e \xab\u0443\u043c\u043d\u0435\u0435\xbb \u0441\u0438\u043b\u044c\u043d\u044b\u043c\u0438 \u0434\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432\u0430\u043c\u0438 \u043d\u0435 \u043f\u043e\u0434\u043a\u0440\u0435\u043f\u043b\u0435\u043d\u044b."]],variants:"\u041a\u043b\u0430\u0441\u0441\u0438\u0447\u0435\u0441\u043a\u0430\u044f 9\xd79; \u043c\u0438\u043d\u0438 4\xd74 \u0438 6\xd76; \u0434\u0438\u0430\u0433\u043e\u043d\u0430\u043b\u044c\u043d\u0430\u044f X-Sudoku; Killer (\u0441 \u0441\u0443\u043c\u043c\u0430\u043c\u0438 \u0432 \u043a\u043b\u0435\u0442\u043a\u0430\u0445); \u043d\u0435\u0440\u0435\u0433\u0443\u043b\u044f\u0440\u043d\u044b\u0435 \u043e\u0431\u043b\u0430\u0441\u0442\u0438 (jigsaw); \u043f\u0435\u0440\u0435\u043a\u0440\u044b\u0432\u0430\u044e\u0449\u0438\u0435\u0441\u044f \u0441\u0435\u0442\u043a\u0438 \xab\u0421\u0430\u043c\u0443\u0440\u0430\u0439\xbb."},en:{about:"A logic placement puzzle on a 6\xd76 grid \u2014 a gentler cousin of the classic 9\xd79. Fill every row, column and box so each digit appears exactly once. No arithmetic; pure deduction.",benefit:"Systematic logical reasoning, working memory (holding candidate options in mind), patience, and the habit of testing a hypothesis before committing to it.",history:"Its ancestor is the 18th-century Latin square studied by Leonhard Euler. The modern puzzle appeared as \"Number Place\" in a 1979 Dell magazine, was renamed and popularised in Japan by Nikoli in 1984, and went global in 2004\u20132005.",creator:"The modern form is credited to Howard Garns, a retired American architect, who published it anonymously in 1979. Despite the Japanese name, it was not invented in Japan \u2014 Nikoli popularised it, and Wayne Gould's computer generator drove the 2004 worldwide boom.",methods:"Start from the most constrained cell \u2014 the row, column or box with the fewest options. Pencil in candidates, eliminate by scanning, and never guess on a 6\xd76: every step should be forced by logic.",duration:"There is no daily dose that \"rewires\" your brain \u2014 treat it as enjoyable logic practice. One or two puzzles when you want a focused break is plenty.",research:"The honest version: puzzles like Sudoku reliably make you better at Sudoku. Large studies link regular puzzling with sharper reasoning in older adults, but causation is unproven \u2014 sharper minds may simply puzzle more. Do not expect it to prevent cognitive decline.",rec:"Use it to practise patient, error-free deduction. Step up to 9\xd79 and harder variants once 6\xd76 feels automatic.",faq:[["Is Sudoku Japanese?","The name is; the puzzle is not. The modern form was created in the USA in 1979 \u2014 Japan\u2019s Nikoli popularised and renamed it."],["Does it need maths?","No. The digits are just symbols; it is pure logic, never arithmetic."],["Does it make you smarter?","It makes you better at logic puzzles. Broad \"smarter\" claims are not backed by strong evidence."]],variants:"Classic 9\xd79; mini 4\xd74 and 6\xd76; Diagonal / X-Sudoku; Killer Sudoku (with cage sums); Irregular jigsaw regions; and Samurai overlapping grids."},es:{about:"Un rompecabezas de colocaci\xf3n l\xf3gica en una cuadr\xedcula de 6\xd76, un primo m\xe1s suave del cl\xe1sico 9\xd79. Rellena cada fila, columna y caja de modo que cada d\xedgito aparezca exactamente una vez. Sin aritm\xe9tica; pura deducci\xf3n.",benefit:"Razonamiento l\xf3gico sistem\xe1tico, memoria de trabajo (retener en la mente las opciones candidatas), paciencia y el h\xe1bito de poner a prueba una hip\xf3tesis antes de comprometerte con ella.",history:"Su antepasado es el cuadrado latino del siglo XVIII estudiado por Leonhard Euler. El rompecabezas moderno apareci\xf3 como \"Number Place\" en una revista de Dell en 1979, fue rebautizado y popularizado en Jap\xf3n por Nikoli en 1984, y se hizo global en 2004-2005.",creator:"La forma moderna se atribuye a Howard Garns, un arquitecto estadounidense jubilado, que la public\xf3 de forma an\xf3nima en 1979. A pesar del nombre japon\xe9s, no se invent\xf3 en Jap\xf3n: Nikoli lo populariz\xf3, y el generador inform\xe1tico de Wayne Gould impuls\xf3 el auge mundial de 2004.",methods:"Empieza por la celda m\xe1s restringida: la fila, columna o caja con menos opciones. Anota los candidatos a l\xe1piz, elimina escaneando, y nunca adivines en un 6\xd76: cada paso deber\xeda venir forzado por la l\xf3gica.",duration:"No hay una dosis diaria que \"recablee\" tu cerebro: t\xf3malo como una pr\xe1ctica l\xf3gica entretenida. Uno o dos rompecabezas cuando quieras una pausa concentrada es de sobra.",research:"La versi\xf3n honesta: los rompecabezas como el Sudoku te hacen, de forma fiable, mejor en Sudoku. Grandes estudios vinculan el resolver rompecabezas con regularidad con un razonamiento m\xe1s agudo en adultos mayores, pero la causalidad no est\xe1 demostrada: puede que las mentes m\xe1s agudas simplemente jueguen m\xe1s. No esperes que prevenga el deterioro cognitivo.",rec:"\xdasalo para practicar una deducci\xf3n paciente y sin errores. Da el salto al 9\xd79 y a variantes m\xe1s dif\xedciles cuando el 6\xd76 te resulte autom\xe1tico.",faq:[["\xbfEl Sudoku es japon\xe9s?","El nombre lo es; el rompecabezas no. La forma moderna se cre\xf3 en EE. UU. en 1979; el Nikoli de Jap\xf3n lo populariz\xf3 y lo rebautiz\xf3."],["\xbfHace falta matem\xe1ticas?","No. Los d\xedgitos son solo s\xedmbolos; es pura l\xf3gica, nunca aritm\xe9tica."],["\xbfTe hace m\xe1s inteligente?","Te hace mejor en los rompecabezas de l\xf3gica. Las afirmaciones amplias de ser \"m\xe1s inteligente\" no est\xe1n respaldadas por evidencia s\xf3lida."]],variants:"Cl\xe1sico 9\xd79; mini 4\xd74 y 6\xd76; Sudoku diagonal / X-Sudoku; Killer Sudoku (con sumas en jaulas); regiones irregulares tipo rompecabezas; y cuadr\xedculas superpuestas tipo Samur\xe1i."},de:{about:"Ein logisches Setzr\xe4tsel auf einem 6\xd76-Raster \u2013 ein sanfterer Verwandter des klassischen 9\xd79. F\xfclle jede Zeile, Spalte und jeden Block so, dass jede Ziffer genau einmal vorkommt. Keine Rechnerei; reine Deduktion.",benefit:"Systematisches logisches Schlie\xdfen, Arbeitsged\xe4chtnis (Kandidatenoptionen im Kopf behalten), Geduld und die Gewohnheit, eine Annahme zu pr\xfcfen, bevor man sich festlegt.",history:"Sein Vorfahre ist das lateinische Quadrat des 18. Jahrhunderts, das von Leonhard Euler untersucht wurde. Das moderne R\xe4tsel erschien 1979 als \"Number Place\" in einem Dell-Magazin, wurde 1984 in Japan von Nikoli umbenannt und popul\xe4r gemacht und ging 2004\u20132005 um die Welt.",creator:"Die moderne Form wird Howard Garns zugeschrieben, einem pensionierten amerikanischen Architekten, der sie 1979 anonym ver\xf6ffentlichte. Trotz des japanischen Namens wurde es nicht in Japan erfunden \u2013 Nikoli machte es popul\xe4r, und Wayne Goulds Computergenerator trieb den weltweiten Boom von 2004 an.",methods:"Beginne bei der am st\xe4rksten eingeschr\xe4nkten Zelle \u2013 der Zeile, Spalte oder dem Block mit den wenigsten Optionen. Trage Kandidaten als Notiz ein, schlie\xdfe durch Abscannen aus und rate bei einem 6\xd76 nie: Jeder Schritt sollte logisch erzwungen sein.",duration:"Es gibt keine Tagesdosis, die dein Gehirn \"umverdrahtet\" \u2013 betrachte es als angenehme Logik\xfcbung. Ein oder zwei R\xe4tsel, wenn du eine konzentrierte Pause m\xf6chtest, sind v\xf6llig genug.",research:"Die ehrliche Fassung: R\xe4tsel wie Sudoku machen dich zuverl\xe4ssig besser im Sudoku. Gro\xdfe Studien bringen regelm\xe4\xdfiges Knobeln mit sch\xe4rferem Denken bei \xe4lteren Erwachsenen in Verbindung, doch die Ursache ist unbewiesen \u2013 sch\xe4rfere K\xf6pfe knobeln vielleicht einfach mehr. Erwarte nicht, dass es kognitivem Abbau vorbeugt.",rec:"Nutze es, um geduldige, fehlerfreie Deduktion zu \xfcben. Steige auf 9\xd79 und schwerere Varianten um, sobald sich 6\xd76 automatisch anf\xfchlt.",faq:[["Ist Sudoku japanisch?","Der Name ist es; das R\xe4tsel nicht. Die moderne Form entstand 1979 in den USA \u2013 Japans Nikoli machte es popul\xe4r und benannte es um."],["Braucht es Mathematik?","Nein. Die Ziffern sind nur Symbole; es ist reine Logik, nie Rechnerei."],["Macht es einen kl\xfcger?","Es macht dich besser in Logikr\xe4tseln. Weitreichende Behauptungen, kl\xfcger zu werden, sind nicht durch starke Belege gedeckt."]],variants:"Klassisches 9\xd79; Mini-4\xd74 und 6\xd76; Diagonal- / X-Sudoku; Killer-Sudoku (mit K\xe4figsummen); unregelm\xe4\xdfige Puzzleregionen; und \xfcberlappende Samurai-Raster."},pt:{about:"Um quebra-cabe\xe7a de l\xf3gica de posicionamento numa grade 6\xd76 \u2014 um primo mais suave do cl\xe1ssico 9\xd79. Preencha cada linha, coluna e bloco para que cada d\xedgito apare\xe7a exatamente uma vez. Sem aritm\xe9tica; pura dedu\xe7\xe3o.",benefit:"Racioc\xednio l\xf3gico sistem\xe1tico, mem\xf3ria de trabalho (manter na cabe\xe7a as op\xe7\xf5es candidatas), paci\xeancia e o h\xe1bito de testar uma hip\xf3tese antes de se comprometer com ela.",history:"Seu ancestral \xe9 o quadrado latino do s\xe9culo XVIII estudado por Leonhard Euler. O quebra-cabe\xe7a moderno surgiu como \"Number Place\" numa revista da Dell em 1979, foi rebatizado e popularizado no Jap\xe3o pela Nikoli em 1984 e ganhou o mundo em 2004\u20132005.",creator:"A forma moderna \xe9 creditada a Howard Garns, um arquiteto americano aposentado, que a publicou de forma an\xf4nima em 1979. Apesar do nome japon\xeas, ele n\xe3o foi inventado no Jap\xe3o \u2014 a Nikoli o popularizou, e o gerador de computador de Wayne Gould impulsionou o boom mundial de 2004.",methods:"Comece pela c\xe9lula mais restrita \u2014 a linha, coluna ou bloco com menos op\xe7\xf5es. Anote os candidatos a l\xe1pis, elimine por varredura e nunca chute num 6\xd76: cada passo deve ser for\xe7ado pela l\xf3gica.",duration:"N\xe3o existe dose di\xe1ria que \"reconfigure\" o seu c\xe9rebro \u2014 encare-o como uma pr\xe1tica agrad\xe1vel de l\xf3gica. Um ou dois quebra-cabe\xe7as quando voc\xea quiser uma pausa concentrada j\xe1 bastam.",research:"A vers\xe3o honesta: quebra-cabe\xe7as como o Sudoku deixam voc\xea de forma confi\xe1vel melhor em Sudoku. Grandes estudos associam o h\xe1bito regular de quebra-cabe\xe7as a um racioc\xednio mais agu\xe7ado em adultos mais velhos, mas a causalidade n\xe3o est\xe1 comprovada \u2014 mentes mais agu\xe7adas talvez simplesmente fa\xe7am mais quebra-cabe\xe7as. N\xe3o espere que ele previna o decl\xednio cognitivo.",rec:"Use-o para praticar a dedu\xe7\xe3o paciente e sem erros. Avance para o 9\xd79 e variantes mais dif\xedceis quando o 6\xd76 ficar autom\xe1tico.",faq:[["O Sudoku \xe9 japon\xeas?","O nome \xe9; o quebra-cabe\xe7a n\xe3o. A forma moderna foi criada nos EUA em 1979 \u2014 a Nikoli, do Jap\xe3o, o popularizou e rebatizou."],["Precisa de matem\xe1tica?","N\xe3o. Os d\xedgitos s\xe3o apenas s\xedmbolos; \xe9 pura l\xf3gica, nunca aritm\xe9tica."],["Ele deixa voc\xea mais inteligente?","Ele deixa voc\xea melhor em quebra-cabe\xe7as de l\xf3gica. As alega\xe7\xf5es amplas de \"mais inteligente\" n\xe3o t\xeam respaldo em evid\xeancias fortes."]],variants:"Cl\xe1ssico 9\xd79; mini 4\xd74 e 6\xd76; Diagonal / X-Sudoku; Killer Sudoku (com somas em gaiolas); regi\xf5es irregulares em quebra-cabe\xe7a; e grades sobrepostas Samurai."},hi:{about:"6\xd76 \u0917\u094d\u0930\u093f\u0921 \u092a\u0930 \u090f\u0915 \u0924\u0930\u094d\u0915-\u0906\u0927\u093e\u0930\u093f\u0924 \u0938\u094d\u0925\u093e\u0928-\u0928\u093f\u0930\u094d\u0927\u093e\u0930\u0923 \u092a\u0939\u0947\u0932\u0940 \u2014 \u0915\u094d\u0932\u093e\u0938\u093f\u0915 9\xd79 \u0915\u093e \u090f\u0915 \u0928\u0930\u092e \u091a\u091a\u0947\u0930\u093e \u092d\u093e\u0908\u0964 \u0939\u0930 \u092a\u0902\u0915\u094d\u0924\u093f, \u0938\u094d\u0924\u0902\u092d \u0914\u0930 \u092c\u0915\u094d\u0938\u0947 \u0915\u094b \u0907\u0938 \u0924\u0930\u0939 \u092d\u0930\u093f\u090f \u0915\u093f \u0939\u0930 \u0905\u0902\u0915 \u0920\u0940\u0915 \u090f\u0915 \u092c\u093e\u0930 \u0906\u090f\u0964 \u0915\u094b\u0908 \u0905\u0902\u0915\u0917\u0923\u093f\u0924 \u0928\u0939\u0940\u0902; \u0938\u093f\u0930\u094d\u092b\u093c \u0928\u093f\u0917\u092e\u0928 (deduction)\u0964",benefit:"\u0935\u094d\u092f\u0935\u0938\u094d\u0925\u093f\u0924 \u0924\u093e\u0930\u094d\u0915\u093f\u0915 \u0924\u0930\u094d\u0915, \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932 \u0938\u094d\u092e\u0943\u0924\u093f (\u0938\u0902\u092d\u093e\u0935\u093f\u0924 \u0935\u093f\u0915\u0932\u094d\u092a\u094b\u0902 \u0915\u094b \u092e\u0928 \u092e\u0947\u0902 \u0925\u093e\u092e\u0928\u093e), \u0927\u0948\u0930\u094d\u092f, \u0914\u0930 \u0915\u093f\u0938\u0940 \u0928\u093f\u0937\u094d\u0915\u0930\u094d\u0937 \u092a\u0930 \u091f\u093f\u0915\u0928\u0947 \u0938\u0947 \u092a\u0939\u0932\u0947 \u090f\u0915 \u092a\u0930\u093f\u0915\u0932\u094d\u092a\u0928\u093e \u0915\u094b \u092a\u0930\u0916\u0928\u0947 \u0915\u0940 \u0906\u0926\u0924\u0964",history:"\u0907\u0938\u0915\u093e \u092a\u0942\u0930\u094d\u0935\u091c 18\u0935\u0940\u0902 \u0938\u0926\u0940 \u0915\u093e \u0932\u0948\u091f\u093f\u0928 \u0935\u0930\u094d\u0917 \u0939\u0948 \u091c\u093f\u0938\u0915\u093e \u0905\u0927\u094d\u092f\u092f\u0928 Leonhard Euler \u0928\u0947 \u0915\u093f\u092f\u093e \u0925\u093e\u0964 \u0906\u0927\u0941\u0928\u093f\u0915 \u092a\u0939\u0947\u0932\u0940 1979 \u0915\u0940 \u090f\u0915 Dell \u092a\u0924\u094d\u0930\u093f\u0915\u093e \u092e\u0947\u0902 \"Number Place\" \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u0938\u093e\u092e\u0928\u0947 \u0906\u0908, \u091c\u093e\u092a\u093e\u0928 \u092e\u0947\u0902 Nikoli \u0928\u0947 1984 \u092e\u0947\u0902 \u0907\u0938\u0915\u093e \u0928\u093e\u092e \u092c\u0926\u0932\u0915\u0930 \u0907\u0938\u0947 \u0932\u094b\u0915\u092a\u094d\u0930\u093f\u092f \u092c\u0928\u093e\u092f\u093e, \u0914\u0930 2004\u20132005 \u092e\u0947\u0902 \u092f\u0939 \u0926\u0941\u0928\u093f\u092f\u093e \u092d\u0930 \u092e\u0947\u0902 \u092b\u0948\u0932 \u0917\u0908\u0964",creator:"\u0906\u0927\u0941\u0928\u093f\u0915 \u0930\u0942\u092a \u0915\u093e \u0936\u094d\u0930\u0947\u092f Howard Garns \u0915\u094b \u0926\u093f\u092f\u093e \u091c\u093e\u0924\u093e \u0939\u0948, \u091c\u094b \u090f\u0915 \u0938\u0947\u0935\u093e\u0928\u093f\u0935\u0943\u0924\u094d\u0924 \u0905\u092e\u0947\u0930\u093f\u0915\u0940 \u0935\u093e\u0938\u094d\u0924\u0941\u0915\u093e\u0930 \u0925\u0947 \u0914\u0930 \u091c\u093f\u0928\u094d\u0939\u094b\u0902\u0928\u0947 \u0907\u0938\u0947 1979 \u092e\u0947\u0902 \u0917\u0941\u092e\u0928\u093e\u092e \u0930\u0942\u092a \u0938\u0947 \u092a\u094d\u0930\u0915\u093e\u0936\u093f\u0924 \u0915\u093f\u092f\u093e\u0964 \u091c\u093e\u092a\u093e\u0928\u0940 \u0928\u093e\u092e \u0915\u0947 \u092c\u093e\u0935\u091c\u0942\u0926, \u0907\u0938\u0915\u093e \u0906\u0935\u093f\u0937\u094d\u0915\u093e\u0930 \u091c\u093e\u092a\u093e\u0928 \u092e\u0947\u0902 \u0928\u0939\u0940\u0902 \u0939\u0941\u0906 \u0925\u093e \u2014 Nikoli \u0928\u0947 \u0907\u0938\u0947 \u0932\u094b\u0915\u092a\u094d\u0930\u093f\u092f \u092c\u0928\u093e\u092f\u093e, \u0914\u0930 Wayne Gould \u0915\u0947 \u0915\u0902\u092a\u094d\u092f\u0942\u091f\u0930 \u091c\u0928\u0930\u0947\u091f\u0930 \u0928\u0947 2004 \u0915\u0947 \u0935\u093f\u0936\u094d\u0935\u0935\u094d\u092f\u093e\u092a\u0940 \u0909\u091b\u093e\u0932 \u0915\u094b \u0906\u0917\u0947 \u092c\u0922\u093c\u093e\u092f\u093e\u0964",methods:"\u0938\u092c\u0938\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u092c\u0902\u0927\u0947 \u0939\u0941\u090f \u0916\u093c\u093e\u0928\u0947 \u0938\u0947 \u0936\u0941\u0930\u0942 \u0915\u0940\u091c\u093f\u090f \u2014 \u0935\u0939 \u092a\u0902\u0915\u094d\u0924\u093f, \u0938\u094d\u0924\u0902\u092d \u092f\u093e \u092c\u0915\u094d\u0938\u093e \u091c\u093f\u0938\u092e\u0947\u0902 \u0938\u092c\u0938\u0947 \u0915\u092e \u0935\u093f\u0915\u0932\u094d\u092a \u0939\u094b\u0902\u0964 \u0938\u0902\u092d\u093e\u0935\u093f\u0924 \u0905\u0902\u0915\u094b\u0902 \u0915\u094b \u0939\u0932\u094d\u0915\u0947 \u0938\u0947 \u0932\u093f\u0916\u093f\u090f, \u0938\u094d\u0915\u0948\u0928 \u0915\u0930\u0915\u0947 \u0909\u0928\u094d\u0939\u0947\u0902 \u0939\u091f\u093e\u0924\u0947 \u091c\u093e\u0907\u090f, \u0914\u0930 6\xd76 \u092a\u0930 \u0915\u092d\u0940 \u0905\u0902\u0926\u093e\u091c\u093c\u093e \u092e\u0924 \u0932\u0917\u093e\u0907\u090f: \u0939\u0930 \u0915\u093c\u0926\u092e \u0924\u0930\u094d\u0915 \u0938\u0947 \u092e\u091c\u092c\u0942\u0930 \u0939\u094b\u0928\u093e \u091a\u093e\u0939\u093f\u090f\u0964",duration:"\u0910\u0938\u0940 \u0915\u094b\u0908 \u0930\u094b\u091c\u093c \u0915\u0940 \u0916\u093c\u0941\u0930\u093e\u0915 \u0928\u0939\u0940\u0902 \u0939\u0948 \u091c\u094b \u0906\u092a\u0915\u0947 \u0926\u093f\u092e\u093e\u0917 \u0915\u094b \"\u092b\u093f\u0930 \u0938\u0947 \u0924\u093e\u0930\" \u0926\u0947 \u2014 \u0907\u0938\u0947 \u090f\u0915 \u0906\u0928\u0902\u0926\u0926\u093e\u092f\u0915 \u0924\u0930\u094d\u0915-\u0905\u092d\u094d\u092f\u093e\u0938 \u092e\u093e\u0928\u093f\u090f\u0964 \u091c\u092c \u0906\u092a\u0915\u094b \u090f\u0915 \u090f\u0915\u093e\u0917\u094d\u0930 \u0935\u093f\u0930\u093e\u092e \u091a\u093e\u0939\u093f\u090f \u0924\u092c \u090f\u0915 \u092f\u093e \u0926\u094b \u092a\u0939\u0947\u0932\u093f\u092f\u093e\u0901 \u0915\u093e\u092b\u093c\u0940 \u0939\u0948\u0902\u0964",research:"\u0908\u092e\u093e\u0928\u0926\u093e\u0930 \u0930\u0942\u092a \u092f\u0939 \u0939\u0948: Sudoku \u091c\u0948\u0938\u0940 \u092a\u0939\u0947\u0932\u093f\u092f\u093e\u0901 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0922\u0902\u0917 \u0938\u0947 \u0906\u092a\u0915\u094b Sudoku \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u092c\u0928\u093e\u0924\u0940 \u0939\u0948\u0902\u0964 \u092c\u0921\u093c\u0947 \u0905\u0927\u094d\u092f\u092f\u0928 \u0928\u093f\u092f\u092e\u093f\u0924 \u092a\u0939\u0947\u0932\u0940-\u0939\u0932 \u0915\u094b \u092c\u0941\u091c\u093c\u0941\u0930\u094d\u0917\u094b\u0902 \u092e\u0947\u0902 \u0924\u0947\u091c\u093c \u0924\u0930\u094d\u0915 \u0938\u0947 \u091c\u094b\u0921\u093c\u0924\u0947 \u0939\u0948\u0902, \u092a\u0930 \u0915\u093e\u0930\u0923-\u0938\u0902\u092c\u0902\u0927 \u0938\u093f\u0926\u094d\u0927 \u0928\u0939\u0940\u0902 \u0939\u0948 \u2014 \u0939\u094b \u0938\u0915\u0924\u093e \u0939\u0948 \u0924\u0947\u091c\u093c \u0926\u093f\u092e\u093e\u0917 \u0935\u093e\u0932\u0947 \u0932\u094b\u0917 \u092c\u0938 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u092a\u0939\u0947\u0932\u093f\u092f\u093e\u0901 \u0939\u0932 \u0915\u0930\u0924\u0947 \u0939\u094b\u0902\u0964 \u092f\u0939 \u0909\u092e\u094d\u092e\u0940\u0926 \u092e\u0924 \u0915\u0940\u091c\u093f\u090f \u0915\u093f \u092f\u0939 \u0938\u0902\u091c\u094d\u091e\u093e\u0928\u093e\u0924\u094d\u092e\u0915 \u0917\u093f\u0930\u093e\u0935\u091f \u0915\u094b \u0930\u094b\u0915\u0947\u0917\u093e\u0964",rec:"\u0907\u0938\u0915\u093e \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0927\u0948\u0930\u094d\u092f\u092a\u0942\u0930\u094d\u0923, \u0917\u093c\u0932\u0924\u0940-\u0930\u0939\u093f\u0924 \u0928\u093f\u0917\u092e\u0928 \u0915\u0947 \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0947 \u0932\u093f\u090f \u0915\u0940\u091c\u093f\u090f\u0964 \u091c\u092c 6\xd76 \u0905\u092a\u0928\u0947-\u0906\u092a \u0939\u094b\u0928\u0947 \u0932\u0917\u0947, \u0924\u092c 9\xd79 \u0914\u0930 \u0915\u0920\u093f\u0928 \u0938\u0902\u0938\u094d\u0915\u0930\u0923\u094b\u0902 \u0915\u0940 \u0913\u0930 \u092c\u0922\u093c\u093f\u090f\u0964",faq:[["\u0915\u094d\u092f\u093e Sudoku \u091c\u093e\u092a\u093e\u0928\u0940 \u0939\u0948?","\u0928\u093e\u092e \u091c\u093e\u092a\u093e\u0928\u0940 \u0939\u0948; \u092a\u0939\u0947\u0932\u0940 \u0928\u0939\u0940\u0902\u0964 \u0906\u0927\u0941\u0928\u093f\u0915 \u0930\u0942\u092a 1979 \u092e\u0947\u0902 \u0905\u092e\u0947\u0930\u093f\u0915\u093e \u092e\u0947\u0902 \u092c\u0928\u093e \u2014 \u091c\u093e\u092a\u093e\u0928 \u0915\u0947 Nikoli \u0928\u0947 \u0907\u0938\u0947 \u0932\u094b\u0915\u092a\u094d\u0930\u093f\u092f \u092c\u0928\u093e\u092f\u093e \u0914\u0930 \u0907\u0938\u0915\u093e \u0928\u093e\u092e \u092c\u0926\u0932\u093e\u0964"],["\u0915\u094d\u092f\u093e \u0907\u0938\u092e\u0947\u0902 \u0917\u0923\u093f\u0924 \u091a\u093e\u0939\u093f\u090f?","\u0928\u0939\u0940\u0902\u0964 \u0905\u0902\u0915 \u092c\u0938 \u091a\u093f\u0939\u094d\u0928 \u0939\u0948\u0902; \u092f\u0939 \u0935\u093f\u0936\u0941\u0926\u094d\u0927 \u0924\u0930\u094d\u0915 \u0939\u0948, \u0915\u092d\u0940 \u0905\u0902\u0915\u0917\u0923\u093f\u0924 \u0928\u0939\u0940\u0902\u0964"],["\u0915\u094d\u092f\u093e \u092f\u0939 \u0906\u092a\u0915\u094b \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0939\u094b\u0936\u093f\u092f\u093e\u0930 \u092c\u0928\u093e\u0924\u093e \u0939\u0948?","\u092f\u0939 \u0906\u092a\u0915\u094b \u0924\u0930\u094d\u0915-\u092a\u0939\u0947\u0932\u093f\u092f\u094b\u0902 \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u092c\u0928\u093e\u0924\u093e \u0939\u0948\u0964 \u0935\u094d\u092f\u093e\u092a\u0915 \"\u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0939\u094b\u0936\u093f\u092f\u093e\u0930\" \u0935\u093e\u0932\u0947 \u0926\u093e\u0935\u094b\u0902 \u0915\u094b \u092e\u091c\u093c\u092c\u0942\u0924 \u0938\u092c\u0942\u0924\u094b\u0902 \u0915\u093e \u0938\u092e\u0930\u094d\u0925\u0928 \u0928\u0939\u0940\u0902 \u0939\u0948\u0964"]],variants:"\u0915\u094d\u0932\u093e\u0938\u093f\u0915 9\xd79; \u092e\u093f\u0928\u0940 4\xd74 \u0914\u0930 6\xd76; Diagonal / X-Sudoku; Killer Sudoku (\u092a\u093f\u0902\u091c\u0930\u094b\u0902 \u0915\u0947 \u092f\u094b\u0917 \u0915\u0947 \u0938\u093e\u0925); \u0905\u0928\u093f\u092f\u092e\u093f\u0924 \u091c\u093f\u0917\u0938\u0949 \u0915\u094d\u0937\u0947\u0924\u094d\u0930; \u0914\u0930 Samurai \u0905\u0924\u093f\u0935\u094d\u092f\u093e\u092a\u0940 \u0917\u094d\u0930\u093f\u0921\u0964"},zh:{about:"\u4e00\u4e2a6\xd76\u65b9\u683c\u4e0a\u7684\u903b\u8f91\u586b\u6570\u8c1c\u9898\u2014\u2014\u7ecf\u51789\xd79\u7684\u6e29\u548c\u7248\u8868\u4eb2\u3002\u628a\u6bcf\u4e00\u884c\u3001\u6bcf\u4e00\u5217\u548c\u6bcf\u4e00\u5bab\u586b\u6ee1\uff0c\u4f7f\u6bcf\u4e2a\u6570\u5b57\u6070\u597d\u51fa\u73b0\u4e00\u6b21\u3002\u4e0d\u6d89\u53ca\u7b97\u672f\uff1b\u7eaf\u7cb9\u9760\u63a8\u7406\u3002",benefit:"\u7cfb\u7edf\u5316\u7684\u903b\u8f91\u63a8\u7406\u3001\u5de5\u4f5c\u8bb0\u5fc6\uff08\u628a\u5019\u9009\u9009\u9879\u8bb0\u5728\u8111\u4e2d\uff09\u3001\u8010\u5fc3\uff0c\u4ee5\u53ca\u300c\u5148\u9a8c\u8bc1\u5047\u8bbe\u3001\u518d\u843d\u5b50\u300d\u7684\u4e60\u60ef\u3002",history:"\u5b83\u7684\u7956\u5148\u662f18\u4e16\u7eaa\u7531Leonhard Euler\u7814\u7a76\u7684\u62c9\u4e01\u65b9\u9635\u3002\u73b0\u4ee3\u8c1c\u9898\u4ee5\u300cNumber Place\u300d\u4e4b\u540d\u51fa\u73b0\u57281979\u5e74\u7684\u4e00\u672cDell\u6742\u5fd7\u4e0a\uff0c1984\u5e74\u7531Nikoli\u5728\u65e5\u672c\u6539\u540d\u5e76\u63a8\u5e7f\uff0c\u5e76\u4e8e2004\u20132005\u5e74\u8d70\u5411\u5168\u7403\u3002",creator:"\u73b0\u4ee3\u5f62\u6001\u5f52\u529f\u4e8eHoward Garns\uff0c\u4e00\u4f4d\u9000\u4f11\u7684\u7f8e\u56fd\u5efa\u7b51\u5e08\uff0c\u4ed6\u4e8e1979\u5e74\u533f\u540d\u53d1\u8868\u4e86\u5b83\u3002\u5c3d\u7ba1\u540d\u5b57\u662f\u65e5\u8bed\u7684\uff0c\u5b83\u5e76\u975e\u5728\u65e5\u672c\u53d1\u660e\u2014\u2014\u662fNikoli\u628a\u5b83\u63a8\u5e7f\u5f00\u6765\uff0c\u800cWayne Gould\u7684\u8ba1\u7b97\u673a\u751f\u6210\u5668\u5219\u63a8\u52a8\u4e862004\u5e74\u7684\u5168\u7403\u70ed\u6f6e\u3002",methods:"\u4ece\u7ea6\u675f\u6700\u5f3a\u7684\u683c\u5b50\u5165\u624b\u2014\u2014\u4e5f\u5c31\u662f\u9009\u9879\u6700\u5c11\u7684\u90a3\u4e00\u884c\u3001\u90a3\u4e00\u5217\u6216\u90a3\u4e00\u5bab\u3002\u7528\u94c5\u7b14\u6807\u51fa\u5019\u9009\u6570\uff0c\u9760\u626b\u63cf\u6765\u6392\u9664\uff0c\u57286\xd76\u91cc\u7edd\u4e0d\u8981\u731c\uff1a\u6bcf\u4e00\u6b65\u90fd\u5e94\u5f53\u7531\u903b\u8f91\u5f3a\u5236\u63a8\u51fa\u3002",duration:"\u5e76\u4e0d\u5b58\u5728\u4ec0\u4e48\u80fd\u300c\u91cd\u5851\u300d\u4f60\u5927\u8111\u7684\u6bcf\u65e5\u5242\u91cf\u2014\u2014\u628a\u5b83\u5f53\u6210\u4ee4\u4eba\u6109\u5feb\u7684\u903b\u8f91\u7ec3\u4e60\u5c31\u597d\u3002\u60f3\u4e13\u6ce8\u5730\u6b47\u4e00\u4f1a\u513f\u65f6\u6765\u4e0a\u4e00\u4e24\u9053\uff0c\u5c31\u8db3\u591f\u4e86\u3002",research:"\u8bda\u5b9e\u7684\u8bf4\u6cd5\u662f\uff1a\u50cf\u6570\u72ec\u8fd9\u6837\u7684\u8c1c\u9898\uff0c\u80fd\u53ef\u9760\u5730\u8ba9\u4f60\u66f4\u64c5\u957f\u6570\u72ec\u3002\u5927\u578b\u7814\u7a76\u53d1\u73b0\uff0c\u7ecf\u5e38\u505a\u8c1c\u9898\u4e0e\u8001\u5e74\u4eba\u66f4\u654f\u9510\u7684\u63a8\u7406\u4e4b\u95f4\u5b58\u5728\u5173\u8054\uff0c\u4f46\u56e0\u679c\u5173\u7cfb\u5e76\u672a\u88ab\u8bc1\u5b9e\u2014\u2014\u4e5f\u53ef\u80fd\u53ea\u662f\u5934\u8111\u672c\u5c31\u66f4\u654f\u9510\u7684\u4eba\u66f4\u7231\u505a\u8c1c\u9898\u3002\u522b\u6307\u671b\u5b83\u80fd\u9632\u6b62\u8ba4\u77e5\u8870\u9000\u3002",rec:"\u7528\u5b83\u6765\u7ec3\u4e60\u8010\u5fc3\u3001\u96f6\u5dee\u9519\u7684\u63a8\u7406\u3002\u7b496\xd76\u73a9\u8d77\u6765\u5df2\u6210\u81ea\u52a8\u53cd\u5e94\uff0c\u518d\u5347\u52309\xd79\u548c\u66f4\u96be\u7684\u53d8\u4f53\u3002",faq:[["\u6570\u72ec\u662f\u65e5\u672c\u7684\u5417\uff1f","\u540d\u5b57\u662f\uff1b\u8c1c\u9898\u4e0d\u662f\u3002\u73b0\u4ee3\u5f62\u6001\u4e8e1979\u5e74\u5728\u7f8e\u56fd\u8bde\u751f\u2014\u2014\u662f\u65e5\u672c\u7684Nikoli\u628a\u5b83\u63a8\u5e7f\u5e76\u6539\u4e86\u540d\u3002"],["\u5b83\u9700\u8981\u6570\u5b66\u5417\uff1f","\u4e0d\u9700\u8981\u3002\u90a3\u4e9b\u6570\u5b57\u53ea\u662f\u7b26\u53f7\uff1b\u5b83\u7eaf\u7cb9\u662f\u903b\u8f91\uff0c\u7edd\u65e0\u7b97\u672f\u3002"],["\u5b83\u80fd\u8ba9\u4f60\u53d8\u806a\u660e\u5417\uff1f","\u5b83\u80fd\u8ba9\u4f60\u66f4\u64c5\u957f\u903b\u8f91\u8c1c\u9898\u3002\u81f3\u4e8e\u5bbd\u6cdb\u7684\u300c\u53d8\u806a\u660e\u300d\u4e4b\u8bf4\uff0c\u5e76\u65e0\u6709\u529b\u8bc1\u636e\u652f\u6301\u3002"]],variants:"\u7ecf\u51789\xd79\uff1b\u8ff7\u4f604\xd74\u548c6\xd76\uff1b\u5bf9\u89d2\u7ebf/X\u6570\u72ec\uff1b\u6740\u624b\u6570\u72ec\uff08\u5e26\u7b3c\u5185\u4e4b\u548c\uff09\uff1b\u4e0d\u89c4\u5219\u62fc\u56fe\u5bab\uff1b\u4ee5\u53ca\u4ea4\u53e0\u6210\u65b9\u9635\u7684Samurai\uff08\u6b66\u58eb\uff09\u6570\u72ec\u3002"}},"switching-task":{ru:{about:"\u0412 \xab\u041f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0435\u043d\u0438\u0438 \u0437\u0430\u0434\u0430\u0447\xbb \u043f\u043e \u044d\u043a\u0440\u0430\u043d\u0443 \u0438\u0434\u0451\u0442 \u043f\u043e\u0442\u043e\u043a \u043e\u0431\u044a\u0435\u043a\u0442\u043e\u0432, \u0430 \u043f\u0440\u0430\u0432\u0438\u043b\u043e, \u043a\u043e\u0442\u043e\u0440\u043e\u0435 \u043a \u043d\u0438\u043c \u043d\u0443\u0436\u043d\u043e \u043f\u0440\u0438\u043c\u0435\u043d\u0438\u0442\u044c, \u043f\u043e\u0441\u0442\u043e\u044f\u043d\u043d\u043e \u043c\u0435\u043d\u044f\u0435\u0442\u0441\u044f. \u0422\u043e \u0432\u044b \u0441\u043e\u0440\u0442\u0438\u0440\u0443\u0435\u0442\u0435 \u0447\u0438\u0441\u043b\u043e \u043f\u043e \u0447\u0451\u0442\u043d\u043e\u0441\u0442\u0438, \u0442\u043e \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u043a\u0430 \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0430\u0435\u0442 \u0432\u0430\u0441 \u043d\u0430 \u0441\u043e\u0440\u0442\u0438\u0440\u043e\u0432\u043a\u0443 \u043f\u043e \u0432\u0435\u043b\u0438\u0447\u0438\u043d\u0435, \u0438 \u043d\u0430 \u043a\u0430\u0436\u0434\u043e\u043c \u0448\u0430\u0433\u0435 \u043f\u0440\u0438\u0445\u043e\u0434\u0438\u0442\u0441\u044f \u0441\u0447\u0438\u0442\u0430\u0442\u044c \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u043a\u0443, \u0441\u0431\u0440\u043e\u0441\u0438\u0442\u044c \u0441\u0442\u0430\u0440\u043e\u0435 \u043f\u0440\u0430\u0432\u0438\u043b\u043e, \u0437\u0430\u0433\u0440\u0443\u0437\u0438\u0442\u044c \u043d\u043e\u0432\u043e\u0435 \u0438 \u0431\u044b\u0441\u0442\u0440\u043e \u043e\u0442\u0432\u0435\u0442\u0438\u0442\u044c, \u043d\u0435 \u0442\u0435\u0440\u044f\u044f \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u0438.",benefit:"\u0422\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442\u0441\u044f \u043a\u043e\u0433\u043d\u0438\u0442\u0438\u0432\u043d\u0430\u044f \u0433\u0438\u0431\u043a\u043e\u0441\u0442\u044c \u0438 \u0443\u043f\u0440\u0430\u0432\u043b\u044f\u044e\u0449\u0438\u0439 \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044c, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u043f\u043e\u0437\u0432\u043e\u043b\u044f\u0435\u0442 \u043f\u043e \u043a\u043e\u043c\u0430\u043d\u0434\u0435 \u043f\u0435\u0440\u0435\u0441\u0442\u0440\u0430\u0438\u0432\u0430\u0442\u044c \u0443\u0441\u0442\u0430\u043d\u043e\u0432\u043a\u0443, \u0442\u0430 \u0436\u0435 \u0441\u0438\u0441\u0442\u0435\u043c\u0430, \u043d\u0430 \u043a\u043e\u0442\u043e\u0440\u0443\u044e \u0432\u044b \u043e\u043f\u0438\u0440\u0430\u0435\u0442\u0435\u0441\u044c, \u043a\u043e\u0433\u0434\u0430 \u0441\u043e\u0432\u043c\u0435\u0449\u0430\u0435\u0442\u0435 \u0434\u0432\u0430 \u0434\u0435\u043b\u0430 \u0438 \u0432\u044b\u043d\u0443\u0436\u0434\u0435\u043d\u044b \u0440\u0430\u0437 \u0437\u0430 \u0440\u0430\u0437\u043e\u043c \u0431\u0440\u043e\u0441\u0430\u0442\u044c \u043e\u0434\u043d\u043e, \u0447\u0442\u043e\u0431\u044b \u0432\u0437\u044f\u0442\u044c\u0441\u044f \u0437\u0430 \u0434\u0440\u0443\u0433\u043e\u0435.",history:"\u042d\u0444\u0444\u0435\u043a\u0442 \u0432\u043f\u0435\u0440\u0432\u044b\u0435 \u043e\u043f\u0438\u0441\u0430\u043b \u0410\u0440\u0442\u0443\u0440 \u0414\u0436\u0435\u0440\u0441\u0438\u043b\u0434 \u0432 1927 \u0433\u043e\u0434\u0443: \u043e\u043d \u0437\u0430\u043c\u0435\u0440\u044f\u043b \u0432\u0440\u0435\u043c\u044f \u043d\u0430 \u0441\u043c\u0435\u0448\u0430\u043d\u043d\u043e\u043c \u0441\u043f\u0438\u0441\u043a\u0435 \u0437\u0430\u0434\u0430\u0447 \u043f\u0440\u043e\u0442\u0438\u0432 \u0441\u043f\u0438\u0441\u043a\u0430 \u0441 \u043e\u0434\u043d\u043e\u0439 \u043f\u043e\u0432\u0442\u043e\u0440\u044f\u044e\u0449\u0435\u0439\u0441\u044f \u0437\u0430\u0434\u0430\u0447\u0435\u0439 \u0438 \u0443\u0432\u0438\u0434\u0435\u043b, \u0447\u0442\u043e \u0441\u043c\u0435\u0448\u0430\u043d\u043d\u044b\u0439 \u043e\u0431\u0445\u043e\u0434\u0438\u0442\u0441\u044f \u0434\u043e\u0440\u043e\u0436\u0435. \u0418\u0434\u0435\u044f \u043f\u043e\u0447\u0442\u0438 \u0437\u0430\u0431\u044b\u043b\u0430\u0441\u044c \u0434\u043e \u0441\u0435\u0440\u0435\u0434\u0438\u043d\u044b 1990-\u0445, \u043a\u043e\u0433\u0434\u0430 \u0432\u043e\u043b\u043d\u0430 \u0440\u0430\u0431\u043e\u0442 \u043f\u043e \u043a\u043e\u0433\u043d\u0438\u0442\u0438\u0432\u043d\u043e\u0439 \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u0438 \u0432\u0435\u0440\u043d\u0443\u043b\u0430 \u0435\u0451 \u043a\u0430\u043a \u0443\u0434\u043e\u0431\u043d\u043e\u0435 \u043e\u043a\u043d\u043e \u0432 \u0443\u043f\u0440\u0430\u0432\u043b\u044f\u044e\u0449\u0438\u0439 \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044c.",creator:"\u0415\u0434\u0438\u043d\u043e\u0433\u043e \u0430\u0432\u0442\u043e\u0440\u0430 \u0443 \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u044f \u043d\u0435\u0442. \u0421\u0440\u0430\u0432\u043d\u0435\u043d\u0438\u0435 \u0432\u0432\u0451\u043b \u0410\u0440\u0442\u0443\u0440 \u0414\u0436\u0435\u0440\u0441\u0438\u043b\u0434 \u0432 1927 \u0433\u043e\u0434\u0443, \u0430 \u0441\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u044b\u0439 \u0432\u0438\u0434 \u0435\u043c\u0443 \u043f\u0440\u0438\u0434\u0430\u043b\u0438 \u0420\u043e\u0431\u0435\u0440\u0442 \u0420\u043e\u0434\u0436\u0435\u0440\u0441 \u0438 \u0421\u0442\u0438\u0432\u0435\u043d \u041c\u043e\u043d\u0441\u0435\u043b\u043b \u0432 1995 \u0433\u043e\u0434\u0443, \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u0432\u0432\u0435\u043b\u0438 \u043f\u043e\u043d\u044f\u0442\u0438\u0435 \xab\u0446\u0435\u043d\u0430 \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0435\u043d\u0438\u044f\xbb \u0438 \u043f\u043e\u0441\u0442\u0440\u043e\u0438\u043b\u0438 \u0440\u0430\u0441\u0442\u0438\u0440\u0430\u0436\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u0443\u044e \u0441\u0445\u0435\u043c\u0443 \u0441 \u0447\u0435\u0440\u0435\u0434\u0443\u044e\u0449\u0438\u043c\u0438\u0441\u044f \u0441\u0435\u0440\u0438\u044f\u043c\u0438.",methods:"\u0421\u0447\u0438\u0442\u044b\u0432\u0430\u0439\u0442\u0435 \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u043a\u0443 \u0440\u0430\u043d\u044c\u0448\u0435, \u0447\u0435\u043c \u0441\u043c\u043e\u0442\u0440\u0438\u0442\u0435 \u043d\u0430 \u0441\u0430\u043c \u043e\u0431\u044a\u0435\u043a\u0442, \u0438 \u043f\u0440\u043e\u0433\u043e\u0432\u0430\u0440\u0438\u0432\u0430\u0439\u0442\u0435 \u043f\u0440\u043e \u0441\u0435\u0431\u044f \u0442\u0435\u043a\u0443\u0449\u0435\u0435 \u043f\u0440\u0430\u0432\u0438\u043b\u043e, \u0447\u0442\u043e\u0431\u044b \u0441\u0442\u0430\u0440\u043e\u0435 \u043d\u0435 \u043f\u0440\u043e\u0441\u043e\u0447\u0438\u043b\u043e\u0441\u044c \u0432 \u043e\u0442\u0432\u0435\u0442. \u041d\u0430\u0440\u0430\u0449\u0438\u0432\u0430\u0439\u0442\u0435 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u043b\u0438\u0448\u044c \u043d\u0430\u0441\u0442\u043e\u043b\u044c\u043a\u043e, \u043d\u0430\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0434\u0435\u0440\u0436\u0438\u0442\u0441\u044f \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u044c, \u0432\u0435\u0434\u044c \u0441\u043f\u0435\u0448\u043a\u0430 \u0440\u0430\u0437\u0434\u0443\u0432\u0430\u0435\u0442 \u043e\u0448\u0438\u0431\u043a\u0438, \u0430 \u043d\u0435 \u0443\u043c\u0435\u043d\u044c\u0448\u0430\u0435\u0442 \u0446\u0435\u043d\u0443 \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0435\u043d\u0438\u044f, \u0438 \u0443\u0434\u043b\u0438\u043d\u044f\u0439\u0442\u0435 \u043f\u0430\u0443\u0437\u0443 \u043f\u0435\u0440\u0435\u0434 \u0441\u043c\u0435\u043d\u043e\u0439 \u043f\u0440\u0430\u0432\u0438\u043b\u0430, \u043a\u043e\u0433\u0434\u0430 \u0445\u043e\u0442\u0438\u0442\u0435 \u043f\u043e\u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u0437\u0430\u0431\u043b\u0430\u0433\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u0443\u044e \u043f\u043e\u0434\u0433\u043e\u0442\u043e\u0432\u043a\u0443.",duration:"\u041b\u0443\u0447\u0448\u0435 \u0432\u0441\u0435\u0433\u043e \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u0435 \u0441\u043e\u0441\u0440\u0435\u0434\u043e\u0442\u043e\u0447\u0435\u043d\u043d\u044b\u0435 \u043f\u043e\u0434\u0445\u043e\u0434\u044b, \u043f\u0440\u0438\u043c\u0435\u0440\u043d\u043e \u043f\u043e 5\u201310 \u043c\u0438\u043d\u0443\u0442, \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0434\u043d\u0435\u0439 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e. \u041f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0435\u043d\u0438\u0435 \u0441\u0438\u043b\u044c\u043d\u043e \u043d\u0430\u0433\u0440\u0443\u0436\u0430\u0435\u0442 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u043a\u0430\u0447\u0435\u0441\u0442\u0432\u043e \u0431\u044b\u0441\u0442\u0440\u043e \u043f\u0430\u0434\u0430\u0435\u0442 \u043f\u0440\u0438 \u0443\u0441\u0442\u0430\u043b\u043e\u0441\u0442\u0438, \u0438 \u043e\u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u044c\u0441\u044f \u043d\u0430 \u043f\u0438\u043a\u0435 \u043b\u0443\u0447\u0448\u0435, \u0447\u0435\u043c \u0434\u043e\u0442\u044f\u0433\u0438\u0432\u0430\u0442\u044c \u0434\u043b\u0438\u043d\u043d\u0443\u044e \u0441\u0435\u0441\u0441\u0438\u044e \u0447\u0435\u0440\u0435\u0437 \u0441\u0438\u043b\u0443.",research:"\u0422\u0432\u0451\u0440\u0434\u043e \u0434\u043e\u043a\u0430\u0437\u0430\u043d\u043e \u0440\u043e\u0432\u043d\u043e \u0442\u043e, \u0447\u0435\u0433\u043e \u0438 \u0441\u0442\u043e\u0438\u0442 \u0436\u0434\u0430\u0442\u044c: \u0446\u0435\u043d\u0430 \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0435\u043d\u0438\u044f \u2014 \u0443\u0441\u0442\u043e\u0439\u0447\u0438\u0432\u044b\u0439, \u043d\u0430\u0434\u0451\u0436\u043d\u043e \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0438\u043c\u044b\u0439 \u044d\u0444\u0444\u0435\u043a\u0442, \u0438 \u0441 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u043e\u0439 \u0432\u044b \u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u0435\u0441\u044c \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u0438 \u0442\u043e\u0447\u043d\u0435\u0435 \u0432 \u0441\u0430\u043c\u043e\u0439 \u0437\u0430\u0434\u0430\u0447\u0435 \u043d\u0430 \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0435\u043d\u0438\u0435. \u0413\u0440\u043e\u043c\u043a\u0438\u0435 \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f \u043a\u0443\u0434\u0430 \u0441\u043b\u0430\u0431\u0435\u0435: \u0448\u0438\u0440\u043e\u043a\u0438\u0439 \u043f\u0435\u0440\u0435\u043d\u043e\u0441 \u043d\u0430 \u0431\u044b\u0442\u043e\u0432\u0443\u044e \u043c\u043d\u043e\u0433\u043e\u0437\u0430\u0434\u0430\u0447\u043d\u043e\u0441\u0442\u044c, \u043e\u0431\u0449\u0438\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0438\u043b\u0438 \u0437\u0430\u0449\u0438\u0442\u0443 \u043e\u0442 \u0432\u043e\u0437\u0440\u0430\u0441\u0442\u043d\u043e\u0433\u043e \u0441\u043f\u0430\u0434\u0430 \u0441\u043b\u0430\u0431\u043e \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0451\u043d \u0438 \u043e\u0441\u043f\u0430\u0440\u0438\u0432\u0430\u0435\u0442\u0441\u044f, \u0430 \u0441\u0430\u043c\u044b\u0435 \u0441\u0442\u0440\u043e\u0433\u0438\u0435 \u043e\u0431\u0437\u043e\u0440\u044b \u0442\u0440\u0435\u043d\u0430\u0436\u0451\u0440\u043e\u0432 \u0434\u043b\u044f \u043c\u043e\u0437\u0433\u0430, \u043d\u0430\u043f\u0440\u0438\u043c\u0435\u0440 \u0440\u0430\u0431\u043e\u0442\u0430 \u0421\u0430\u0439\u043c\u043e\u043d\u0441\u0430 \u0441 \u043a\u043e\u043b\u043b\u0435\u0433\u0430\u043c\u0438 2016 \u0433\u043e\u0434\u0430, \u0437\u0430\u043a\u043b\u044e\u0447\u0430\u044e\u0442, \u0447\u0442\u043e \u0437\u0430\u044f\u0432\u043b\u0435\u043d\u0438\u044f \u043e \u0434\u0430\u043b\u044c\u043d\u0435\u043c \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0435 \u043f\u043e \u0431\u043e\u043b\u044c\u0448\u0435\u0439 \u0447\u0430\u0441\u0442\u0438 \u043d\u0435 \u043f\u043e\u0434\u043a\u0440\u0435\u043f\u043b\u0435\u043d\u044b, \u0442\u0430\u043a \u0447\u0442\u043e \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u0435\u0441\u044c \u043a \u043d\u0438\u043c \u0441 \u043e\u0441\u0442\u043e\u0440\u043e\u0436\u043d\u043e\u0441\u0442\u044c\u044e.",rec:"\u041e\u0442\u043d\u043e\u0441\u0438\u0442\u0435\u0441\u044c \u043a \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u043a\u0435 \u043a\u0430\u043a \u043a \u043d\u0430\u0441\u0442\u043e\u044f\u0449\u0435\u0439 \u0437\u0430\u0434\u0430\u0447\u0435: \u0437\u0430\u0434\u0435\u0440\u0436\u0438\u0442\u0435\u0441\u044c \u043d\u0430 \u043c\u0433\u043d\u043e\u0432\u0435\u043d\u0438\u0435, \u0447\u0442\u043e\u0431\u044b \u043e\u0441\u043e\u0437\u043d\u0430\u0442\u044c \u043f\u0440\u0430\u0432\u0438\u043b\u043e, \u043f\u0440\u0435\u0436\u0434\u0435 \u0447\u0435\u043c \u043e\u0442\u0432\u0435\u0447\u0430\u0442\u044c, \u0438 \u0434\u043e\u043b\u044f \u043e\u0448\u0438\u0431\u043e\u043a \u0443\u043f\u0430\u0434\u0451\u0442 \u0431\u044b\u0441\u0442\u0440\u0435\u0435, \u0447\u0435\u043c \u0432\u0440\u0435\u043c\u044f \u0440\u0435\u0430\u043a\u0446\u0438\u0438.",faq:[["\u041f\u043e\u0447\u0435\u043c\u0443 \u0441\u0440\u0430\u0437\u0443 \u043f\u043e\u0441\u043b\u0435 \u0441\u043c\u0435\u043d\u044b \u043f\u0440\u0430\u0432\u0438\u043b\u0430 \u044f \u043e\u0442\u0432\u0435\u0447\u0430\u044e \u043c\u0435\u0434\u043b\u0435\u043d\u043d\u0435\u0435?","\u042d\u0442\u043e \u0438 \u0435\u0441\u0442\u044c \u0446\u0435\u043d\u0430 \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0435\u043d\u0438\u044f \u2014 \u0432\u0440\u0435\u043c\u044f, \u043a\u043e\u0442\u043e\u0440\u043e\u0435 \u043c\u043e\u0437\u0433\u0443 \u043d\u0443\u0436\u043d\u043e, \u0447\u0442\u043e\u0431\u044b \u0441\u0431\u0440\u043e\u0441\u0438\u0442\u044c \u0441\u0442\u0430\u0440\u043e\u0435 \u043f\u0440\u0430\u0432\u0438\u043b\u043e \u0438 \u0437\u0430\u0433\u0440\u0443\u0437\u0438\u0442\u044c \u043d\u043e\u0432\u043e\u0435. \u0422\u0430\u043a \u0438 \u0434\u043e\u043b\u0436\u043d\u043e \u0431\u044b\u0442\u044c, \u0438\u043c\u0435\u043d\u043d\u043e \u044d\u0442\u043e \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u0435 \u0438\u0437\u043c\u0435\u0440\u044f\u0435\u0442 \u0438 \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442."],["\u0421\u0442\u0430\u043d\u0443 \u043b\u0438 \u044f \u043b\u0443\u0447\u0448\u0435 \u0432 \u0440\u0435\u0430\u043b\u044c\u043d\u043e\u0439 \u043c\u043d\u043e\u0433\u043e\u0437\u0430\u0434\u0430\u0447\u043d\u043e\u0441\u0442\u0438?","\u0412 \u0441\u0430\u043c\u043e\u0439 \u044d\u0442\u043e\u0439 \u0437\u0430\u0434\u0430\u0447\u0435 \u0432\u044b \u043d\u0430\u0434\u0451\u0436\u043d\u043e \u0441\u0442\u0430\u043d\u0435\u0442\u0435 \u043b\u0443\u0447\u0448\u0435, \u043d\u043e \u0434\u0430\u043d\u043d\u044b\u0445 \u043e \u0442\u043e\u043c, \u0447\u0442\u043e \u043d\u0430\u0432\u044b\u043a \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0438\u0442\u0441\u044f \u043d\u0430 \u0431\u044b\u0442\u043e\u0432\u0443\u044e \u043c\u043d\u043e\u0433\u043e\u0437\u0430\u0434\u0430\u0447\u043d\u043e\u0441\u0442\u044c, \u043c\u0430\u043b\u043e \u0438 \u043e\u043d\u0438 \u0441\u043f\u043e\u0440\u043d\u044b. \u0422\u0440\u0435\u043d\u0438\u0440\u0443\u0439\u0442\u0435\u0441\u044c \u0440\u0430\u0434\u0438 \u0431\u043e\u0434\u0440\u043e\u0439 \u0438 \u0446\u0435\u043f\u043a\u043e\u0439 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u0438, \u0430 \u043d\u0435 \u0440\u0430\u0434\u0438 \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f \u0448\u0438\u0440\u043e\u043a\u043e\u0433\u043e \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0430 \u0432 \u0436\u0438\u0437\u043d\u044c."],["\u0421\u0442\u043e\u0438\u0442 \u043b\u0438 \u0433\u043d\u0430\u0442\u044c\u0441\u044f \u0437\u0430 \u043c\u0430\u043a\u0441\u0438\u043c\u0430\u043b\u044c\u043d\u043e\u0439 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c\u044e?","\u041d\u0435\u0442. \u041d\u0430\u0440\u0430\u0449\u0438\u0432\u0430\u0439\u0442\u0435 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u043b\u0438\u0448\u044c \u043d\u0430\u0441\u0442\u043e\u043b\u044c\u043a\u043e, \u043d\u0430\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0434\u0435\u0440\u0436\u0438\u0442\u0441\u044f \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u044c. \u0421\u043f\u0435\u0448\u043a\u0430 \u0432 \u043e\u0441\u043d\u043e\u0432\u043d\u043e\u043c \u0434\u043e\u0431\u0430\u0432\u043b\u044f\u0435\u0442 \u043e\u0448\u0438\u0431\u043e\u043a, \u0430 \u0446\u0435\u043d\u0443 \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0435\u043d\u0438\u044f \u0440\u0435\u0430\u043b\u044c\u043d\u043e \u0441\u043d\u0438\u0436\u0430\u0435\u0442 \u043a\u043e\u0440\u043e\u0442\u043a\u043e\u0435 \u0441\u0447\u0438\u0442\u044b\u0432\u0430\u043d\u0438\u0435 \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u043a\u0438 \u043f\u0435\u0440\u0435\u0434 \u043e\u0442\u0432\u0435\u0442\u043e\u043c."]],variants:"\u0412\u0430\u0440\u0438\u0430\u043d\u0442\u044b \u0440\u0430\u0437\u043b\u0438\u0447\u0430\u044e\u0442\u0441\u044f \u0442\u0435\u043c, \u043a\u0430\u043a \u0441\u0438\u0433\u043d\u0430\u043b\u044f\u0442 \u043e \u0441\u043c\u0435\u043d\u0435 \u043f\u0440\u0430\u0432\u0438\u043b\u0430. \u0427\u0435\u0440\u0435\u0434\u0443\u044e\u0449\u0438\u0435\u0441\u044f \u0441\u0435\u0440\u0438\u0438 \u0438\u0434\u0443\u0442 \u043f\u043e \u0444\u0438\u043a\u0441\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u043e\u043c\u0443 \u0440\u0438\u0441\u0443\u043d\u043a\u0443 \u0432\u0440\u043e\u0434\u0435 \u0410\u0410\u0411\u0411, \u0442\u0430\u043a \u0447\u0442\u043e \u0441\u043c\u0435\u043d\u0443 \u043c\u043e\u0436\u043d\u043e \u043f\u0440\u0435\u0434\u0443\u0433\u0430\u0434\u0430\u0442\u044c; \u044f\u0432\u043d\u0430\u044f \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u043a\u0430 \u043f\u043e\u043a\u0430\u0437\u044b\u0432\u0430\u0435\u0442 \u0441\u0438\u043c\u0432\u043e\u043b \u043d\u0430 \u043a\u0430\u0436\u0434\u043e\u043c \u0448\u0430\u0433\u0435; \u043f\u0440\u043e\u0438\u0437\u0432\u043e\u043b\u044c\u043d\u043e\u0435 \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0435\u043d\u0438\u0435 \u0434\u0430\u0451\u0442 \u0432\u044b\u0431\u0438\u0440\u0430\u0442\u044c \u043f\u0440\u0430\u0432\u0438\u043b\u043e \u0441\u0430\u043c\u043e\u043c\u0443. \u0421\u043b\u043e\u0436\u043d\u043e\u0441\u0442\u044c \u0442\u0430\u043a\u0436\u0435 \u0440\u0430\u0441\u0442\u0451\u0442 \u0441 \u0447\u0438\u0441\u043b\u043e\u043c \u043f\u0440\u0430\u0432\u0438\u043b \u0438 \u0432\u0440\u0435\u043c\u0435\u043d\u0435\u043c, \u043a\u043e\u0442\u043e\u0440\u043e\u0435 \u0434\u0430\u0451\u0442\u0441\u044f \u043d\u0430 \u043f\u043e\u0434\u0433\u043e\u0442\u043e\u0432\u043a\u0443."},en:{about:"Task Switching shows you a stream of items and keeps changing the rule you must apply. One moment you sort a number by odd or even, the next a cue flips you to sorting it by high or low, so on every trial you read the cue, drop the old rule, load the new one, and answer fast without losing accuracy.",benefit:"It trains cognitive flexibility and the executive control that lets you reconfigure a mental set on demand, the same machinery you lean on whenever you juggle two activities and have to keep dropping one to pick up the other.",history:"The effect was first reported by Arthur Jersild in 1927, who timed people running through a mixed list of tasks versus a single repeated one and saw the mixed list cost more. The idea sat largely dormant until the mid-1990s, when a wave of cognitive-psychology work revived it as a clean window into executive control.",creator:"There is no single inventor of the exercise. Arthur Jersild introduced the comparison in 1927, and the modern version was shaped by Robert Rogers and Stephen Monsell in 1995, who coined the term switch cost and built the widely copied alternating-runs paradigm.",methods:"Read the cue before you look at the item, and name the current rule to yourself so the wrong rule does not leak in. Push your speed only as far as your accuracy holds, since rushing inflates errors rather than reducing the switch cost, and lengthen the gap before each switch when you want to practise preparing in advance.",duration:"Short focused blocks work best, roughly 5 to 10 minutes at a time, a few days a week. Switching is mentally taxing, so quality drops quickly once you fatigue, and stopping while still sharp beats grinding a long session.",research:"What is solidly shown is exactly what you would expect: the switch cost is a robust, reliable effect, and with practice you get faster and more accurate at the switching task itself. The bigger promises are far shakier, as broad transfer to everyday multitasking, general intelligence or protection against age-related decline is weak and contested, and the most careful reviews of brain training, such as Simons and colleagues in 2016, conclude that far-transfer claims are largely unsupported, so treat them with caution.",rec:"Treat the cue as the real task: pause a beat to register the rule before answering, and your error rate will fall faster than your reaction time.",faq:[["Why am I slower right after the rule changes?","That slowdown is the switch cost, the time your brain needs to drop the old rule and load the new one. It is normal and is exactly what the exercise measures and trains."],["Will this make me better at multitasking in real life?","It reliably makes you better at this task, but evidence that the skill carries over to everyday multitasking is weak and disputed. Train it because the practice is sharp and engaging, not on a promise of broad real-world transfer."],["Should I go for maximum speed?","No. Push speed only as far as your accuracy holds. Rushing mostly adds errors, while a brief read of the cue before you answer is what actually shrinks the switch cost."]],variants:"Versions differ by how the switch is signalled. Alternating runs follow a fixed pattern like AABB so you can predict the switch, explicit cueing shows a symbol each trial, and voluntary switching lets you choose the rule yourself. Difficulty also scales with the number of rules and the time you get to prepare."},es:{about:"Task Switching te muestra un flujo de elementos y va cambiando la regla que debes aplicar. En un momento clasificas un n\xfamero por par o impar, y al siguiente una pista te hace pasar a clasificarlo por alto o bajo, de modo que en cada ensayo lees la pista, sueltas la regla antigua, cargas la nueva y respondes r\xe1pido sin perder precisi\xf3n.",benefit:"Entrena la flexibilidad cognitiva y el control ejecutivo que te permite reconfigurar un conjunto mental a demanda, la misma maquinaria en la que te apoyas siempre que compaginas dos actividades y tienes que ir soltando una para retomar la otra.",history:"El efecto lo describi\xf3 por primera vez Arthur Jersild en 1927, que cronometr\xf3 a personas recorriendo una lista mixta de tareas frente a una sola tarea repetida y vio que la lista mixta costaba m\xe1s. La idea qued\xf3 pr\xe1cticamente dormida hasta mediados de los a\xf1os noventa, cuando una oleada de trabajos de psicolog\xeda cognitiva la revivi\xf3 como una ventana limpia al control ejecutivo.",creator:"No hay un \xfanico inventor del ejercicio. Arthur Jersild introdujo la comparaci\xf3n en 1927, y la versi\xf3n moderna la dieron forma Robert Rogers y Stephen Monsell en 1995, que acu\xf1aron el t\xe9rmino coste de cambio y construyeron el paradigma de rondas alternas, ampliamente copiado.",methods:"Lee la pista antes de mirar el elemento, y n\xf3mbrate a ti mismo la regla vigente para que la regla equivocada no se cuele. Fuerza la velocidad solo hasta donde tu precisi\xf3n aguante, ya que precipitarte infla los errores en vez de reducir el coste de cambio, y alarga el intervalo previo a cada cambio cuando quieras practicar la preparaci\xf3n por adelantado.",duration:"Los bloques cortos y concentrados funcionan mejor, en torno a 5 a 10 minutos cada vez, unos cuantos d\xedas por semana. Cambiar es mentalmente exigente, as\xed que la calidad cae deprisa en cuanto te fatigas, y parar mientras sigues afilado supera a machacar una sesi\xf3n larga.",research:"Lo que est\xe1 s\xf3lidamente demostrado es justo lo que cabr\xeda esperar: el coste de cambio es un efecto robusto y fiable, y con la pr\xe1ctica te vuelves m\xe1s r\xe1pido y preciso en la propia tarea de cambio. Las promesas mayores son mucho m\xe1s endebles, ya que la transferencia amplia a la multitarea cotidiana, a la inteligencia general o a la protecci\xf3n frente al deterioro asociado a la edad es d\xe9bil y discutida, y las revisiones m\xe1s cuidadosas del entrenamiento cerebral, como la de Simons y colaboradores en 2016, concluyen que las afirmaciones de transferencia lejana carecen en gran medida de respaldo, as\xed que t\xf3malas con cautela.",rec:"Trata la pista como la verdadera tarea: detente un instante para registrar la regla antes de responder, y tu tasa de errores caer\xe1 m\xe1s r\xe1pido que tu tiempo de reacci\xf3n.",faq:[["\xbfPor qu\xe9 voy m\xe1s lento justo despu\xe9s de que cambia la regla?","Ese frenazo es el coste de cambio, el tiempo que tu cerebro necesita para soltar la regla antigua y cargar la nueva. Es normal y es exactamente lo que el ejercicio mide y entrena."],["\xbfEsto me har\xe1 mejor en la multitarea en la vida real?","Te hace mejorar de forma fiable en esta tarea, pero la evidencia de que la destreza se traslade a la multitarea cotidiana es d\xe9bil y discutida. Entr\xe9nalo porque la pr\xe1ctica es aguda y absorbente, no por la promesa de una transferencia amplia al mundo real."],["\xbfDeber\xeda ir a la m\xe1xima velocidad?","No. Fuerza la velocidad solo hasta donde tu precisi\xf3n aguante. Precipitarte sobre todo a\xf1ade errores, mientras que una breve lectura de la pista antes de responder es lo que de verdad reduce el coste de cambio."]],variants:"Las versiones difieren en c\xf3mo se se\xf1ala el cambio. Las rondas alternas siguen un patr\xf3n fijo como AABB para que puedas anticipar el cambio, la se\xf1alizaci\xf3n expl\xedcita muestra un s\xedmbolo en cada ensayo, y el cambio voluntario te deja elegir t\xfa mismo la regla. La dificultad tambi\xe9n escala con el n\xfamero de reglas y con el tiempo que tienes para prepararte."},de:{about:"Task Switching zeigt dir einen Strom von Elementen und \xe4ndert dabei st\xe4ndig die Regel, die du anwenden musst. In einem Moment sortierst du eine Zahl nach gerade oder ungerade, im n\xe4chsten l\xe4sst dich ein Hinweis auf hoch oder niedrig umstellen, sodass du in jedem Durchgang den Hinweis liest, die alte Regel fallen l\xe4sst, die neue l\xe4dst und schnell antwortest, ohne an Genauigkeit zu verlieren.",benefit:"Trainiert werden die kognitive Flexibilit\xe4t und die exekutive Kontrolle, die es dir erlaubt, ein mentales Set auf Abruf umzukonfigurieren \u2013 dieselbe Maschinerie, auf die du dich st\xfctzt, wann immer du zwei T\xe4tigkeiten jonglierst und st\xe4ndig die eine fallen lassen musst, um die andere aufzugreifen.",history:"Der Effekt wurde erstmals 1927 von Arthur Jersild beschrieben, der die Zeit von Personen ma\xdf, die eine gemischte Aufgabenliste gegen\xfcber einer einzigen wiederholten durchliefen, und sah, dass die gemischte Liste mehr kostete. Die Idee lag weitgehend brach, bis sie Mitte der 1990er-Jahre durch eine Welle kognitionspsychologischer Arbeiten als sauberes Fenster auf die exekutive Kontrolle wiederbelebt wurde.",creator:"Es gibt keinen einzelnen Erfinder der \xdcbung. Arthur Jersild f\xfchrte den Vergleich 1927 ein, und die moderne Version pr\xe4gten Robert Rogers und Stephen Monsell im Jahr 1995, die den Begriff Wechselkosten pr\xe4gten und das vielfach kopierte Paradigma der alternierenden Durchg\xe4nge schufen.",methods:"Lies den Hinweis, bevor du das Element ansiehst, und benenne dir die aktuelle Regel selbst, damit die falsche Regel nicht durchsickert. Treib dein Tempo nur so weit, wie deine Genauigkeit h\xe4lt, denn Hetzen bl\xe4ht die Fehler auf, statt die Wechselkosten zu senken, und verl\xe4ngere die Pause vor jedem Wechsel, wenn du das vorausschauende Vorbereiten \xfcben willst.",duration:"Kurze, konzentrierte Bl\xf6cke funktionieren am besten, rund 5 bis 10 Minuten am St\xfcck, an ein paar Tagen die Woche. Das Wechseln ist geistig anstrengend, deshalb f\xe4llt die Qualit\xe4t schnell ab, sobald du erm\xfcdest, und aufzuh\xf6ren, solange du noch scharf bist, schl\xe4gt das Durchackern einer langen Sitzung.",research:"Solide belegt ist genau das, was du erwarten w\xfcrdest: Die Wechselkosten sind ein robuster, verl\xe4sslicher Effekt, und mit \xdcbung wirst du in der Wechselaufgabe selbst schneller und treffsicherer. Die gr\xf6\xdferen Versprechen stehen auf weit wackligeren Beinen, denn eine breite \xdcbertragung auf das allt\xe4gliche Multitasking, die allgemeine Intelligenz oder den Schutz vor altersbedingtem Abbau ist schwach und umstritten, und die sorgf\xe4ltigsten \xdcbersichtsarbeiten zum Gehirntraining, etwa von Simons und Kollegen aus dem Jahr 2016, kommen zu dem Schluss, dass Behauptungen \xfcber Fern-Transfer weitgehend unbelegt sind. Behandle sie daher mit Vorsicht.",rec:"Behandle den Hinweis als die eigentliche Aufgabe: Halte einen Moment inne, um die Regel zu erfassen, bevor du antwortest, und deine Fehlerquote sinkt schneller als deine Reaktionszeit.",faq:[["Warum bin ich direkt nach dem Regelwechsel langsamer?","Diese Verlangsamung sind die Wechselkosten, die Zeit, die dein Gehirn braucht, um die alte Regel fallen zu lassen und die neue zu laden. Das ist normal und genau das, was die \xdcbung misst und trainiert."],["Werde ich dadurch im echten Leben besser im Multitasking?","Es macht dich zuverl\xe4ssig besser in dieser Aufgabe, aber Hinweise darauf, dass sich die F\xe4higkeit auf das allt\xe4gliche Multitasking \xfcbertr\xe4gt, sind schwach und umstritten. Trainiere es, weil die \xdcbung scharf und fesselnd ist, nicht auf das Versprechen einer breiten \xdcbertragung in die reale Welt hin."],["Soll ich auf maximales Tempo gehen?","Nein. Treib das Tempo nur so weit, wie deine Genauigkeit h\xe4lt. Hetzen f\xfcgt meist nur Fehler hinzu, w\xe4hrend ein kurzes Lesen des Hinweises vor der Antwort das ist, was die Wechselkosten tats\xe4chlich schrumpfen l\xe4sst."]],variants:"Die Versionen unterscheiden sich darin, wie der Wechsel angek\xfcndigt wird. Alternierende Durchg\xe4nge folgen einem festen Muster wie AABB, sodass du den Wechsel vorhersehen kannst, die explizite Hinweisgebung zeigt in jedem Durchgang ein Symbol, und das freiwillige Wechseln l\xe4sst dich die Regel selbst w\xe4hlen. Die Schwierigkeit steigt zudem mit der Zahl der Regeln und der Zeit, die du zur Vorbereitung hast."},pt:{about:"A Troca de Tarefas mostra a voc\xea um fluxo de itens e fica mudando a regra que voc\xea precisa aplicar. Num momento voc\xea classifica um n\xfamero por par ou \xedmpar, no instante seguinte uma pista te vira para classific\xe1-lo por alto ou baixo, ent\xe3o a cada tentativa voc\xea l\xea a pista, abandona a regra antiga, carrega a nova e responde r\xe1pido sem perder a precis\xe3o.",benefit:"Treina a flexibilidade cognitiva e o controle executivo que permite reconfigurar um conjunto mental sob demanda, a mesma maquinaria de que voc\xea depende sempre que faz malabarismo com duas atividades e tem de largar uma toda hora para pegar a outra.",history:"O efeito foi descrito pela primeira vez por Arthur Jersild em 1927, que cronometrou pessoas percorrendo uma lista mista de tarefas versus uma \xfanica repetida e viu que a lista mista custava mais. A ideia ficou em grande parte adormecida at\xe9 meados da d\xe9cada de 1990, quando uma onda de trabalhos de psicologia cognitiva a reviveu como uma janela limpa para o controle executivo.",creator:"N\xe3o h\xe1 um \xfanico inventor do exerc\xedcio. Arthur Jersild introduziu a compara\xe7\xe3o em 1927, e a vers\xe3o moderna foi moldada por Robert Rogers e Stephen Monsell em 1995, que cunharam o termo custo de troca e constru\xedram o paradigma de s\xe9ries alternadas amplamente copiado.",methods:"Leia a pista antes de olhar o item, e diga a regra atual a si mesmo para que a regra errada n\xe3o vaze. Aumente a velocidade s\xf3 at\xe9 onde a sua precis\xe3o aguentar, j\xe1 que a pressa infla os erros em vez de reduzir o custo de troca, e alongue o intervalo antes de cada troca quando quiser praticar a prepara\xe7\xe3o antecipada.",duration:"Blocos curtos e focados funcionam melhor, mais ou menos 5 a 10 minutos de cada vez, alguns dias por semana. A troca \xe9 mentalmente exigente, ent\xe3o a qualidade cai r\xe1pido assim que voc\xea se cansa, e parar enquanto ainda est\xe1 afiado vence insistir numa sess\xe3o longa.",research:"O que est\xe1 solidamente demonstrado \xe9 exatamente o que se espera: o custo de troca \xe9 um efeito robusto e confi\xe1vel, e com a pr\xe1tica voc\xea fica mais r\xe1pido e mais preciso na pr\xf3pria tarefa de troca. As promessas maiores s\xe3o bem mais fr\xe1geis, pois a transfer\xeancia ampla para o multitarefa do dia a dia, para a intelig\xeancia geral ou para a prote\xe7\xe3o contra o decl\xednio relacionado \xe0 idade \xe9 fraca e contestada, e as revis\xf5es mais cuidadosas de treino cerebral, como a de Simons e colegas em 2016, concluem que as afirma\xe7\xf5es de transfer\xeancia distante s\xe3o em grande parte sem respaldo, ent\xe3o encare-as com cautela.",rec:"Trate a pista como a tarefa de verdade: fa\xe7a uma pausa de um instante para registrar a regra antes de responder, e a sua taxa de erro vai cair mais r\xe1pido do que o seu tempo de rea\xe7\xe3o.",faq:[["Por que fico mais lento logo depois que a regra muda?","Essa lentid\xe3o \xe9 o custo de troca, o tempo de que o seu c\xe9rebro precisa para largar a regra antiga e carregar a nova. \xc9 normal e \xe9 exatamente o que o exerc\xedcio mede e treina."],["Isso vai me deixar melhor em fazer v\xe1rias coisas ao mesmo tempo na vida real?","Vai te deixar de forma confi\xe1vel melhor nesta tarefa, mas a evid\xeancia de que a habilidade se transfere para o multitarefa do dia a dia \xe9 fraca e contestada. Treine porque a pr\xe1tica \xe9 afiada e envolvente, n\xe3o por uma promessa de transfer\xeancia ampla para o mundo real."],["Devo buscar a velocidade m\xe1xima?","N\xe3o. Aumente a velocidade s\xf3 at\xe9 onde a sua precis\xe3o aguentar. A pressa em geral s\xf3 acrescenta erros, enquanto uma breve leitura da pista antes de responder \xe9 o que de fato encolhe o custo de troca."]],variants:"As vers\xf5es diferem em como a troca \xe9 sinalizada. As s\xe9ries alternadas seguem um padr\xe3o fixo como AABB para que voc\xea possa prever a troca, a sinaliza\xe7\xe3o expl\xedcita mostra um s\xedmbolo a cada tentativa, e a troca volunt\xe1ria deixa voc\xea escolher a regra. A dificuldade tamb\xe9m varia conforme o n\xfamero de regras e o tempo que voc\xea tem para se preparar."},hi:{about:"Task Switching \u0906\u092a\u0915\u094b \u0938\u0902\u0915\u0947\u0924\u094b\u0902 \u0915\u0940 \u090f\u0915 \u0927\u093e\u0930\u093e \u0926\u093f\u0916\u093e\u0924\u093e \u0939\u0948 \u0914\u0930 \u092c\u093e\u0930-\u092c\u093e\u0930 \u0935\u0939 \u0928\u093f\u092f\u092e \u092c\u0926\u0932\u0924\u093e \u0930\u0939\u0924\u093e \u0939\u0948 \u091c\u093f\u0938\u0947 \u0906\u092a\u0915\u094b \u0932\u093e\u0917\u0942 \u0915\u0930\u0928\u093e \u0939\u0948\u0964 \u090f\u0915 \u092a\u0932 \u0906\u092a \u0915\u093f\u0938\u0940 \u0938\u0902\u0916\u094d\u092f\u093e \u0915\u094b \u0938\u092e \u092f\u093e \u0935\u093f\u0937\u092e \u0915\u0947 \u0939\u093f\u0938\u093e\u092c \u0938\u0947 \u091b\u093e\u0901\u091f\u0924\u0947 \u0939\u0948\u0902, \u0905\u0917\u0932\u0947 \u0939\u0940 \u092a\u0932 \u090f\u0915 \u0938\u0902\u0915\u0947\u0924 \u0906\u092a\u0915\u094b \u0909\u0938\u0940 \u0938\u0902\u0916\u094d\u092f\u093e \u0915\u094b \u092c\u0921\u093c\u0940 \u092f\u093e \u091b\u094b\u091f\u0940 \u0915\u0947 \u0939\u093f\u0938\u093e\u092c \u0938\u0947 \u091b\u093e\u0901\u091f\u0928\u0947 \u092a\u0930 \u092a\u0932\u091f \u0926\u0947\u0924\u093e \u0939\u0948 \u2014 \u0924\u094b \u0939\u0930 \u091f\u094d\u0930\u093e\u092f\u0932 \u092a\u0930 \u0906\u092a \u0938\u0902\u0915\u0947\u0924 \u092a\u0922\u093c\u0924\u0947 \u0939\u0948\u0902, \u092a\u0941\u0930\u093e\u0928\u093e \u0928\u093f\u092f\u092e \u091b\u094b\u0921\u093c\u0924\u0947 \u0939\u0948\u0902, \u0928\u092f\u093e \u0928\u093f\u092f\u092e \u0932\u093e\u0926\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u0938\u091f\u0940\u0915\u0924\u093e \u0917\u0901\u0935\u093e\u090f \u092c\u093f\u0928\u093e \u0924\u0947\u091c\u093c\u0940 \u0938\u0947 \u091c\u0935\u093e\u092c \u0926\u0947\u0924\u0947 \u0939\u0948\u0902\u0964",benefit:"\u092f\u0939 \u0938\u0902\u091c\u094d\u091e\u093e\u0928\u093e\u0924\u094d\u092e\u0915 \u0932\u091a\u0940\u0932\u093e\u092a\u0928 (cognitive flexibility) \u0914\u0930 \u0935\u0939 \u0915\u093e\u0930\u094d\u092f\u0915\u093e\u0930\u0940-\u0928\u093f\u092f\u0902\u0924\u094d\u0930\u0923 \u0938\u093e\u0927\u0924\u093e \u0939\u0948 \u091c\u094b \u0906\u092a\u0915\u094b \u092e\u093e\u0901\u0917 \u092a\u0930 \u0905\u092a\u0928\u0940 \u092e\u093e\u0928\u0938\u093f\u0915 \u0935\u094d\u092f\u0935\u0938\u094d\u0925\u093e \u092b\u093f\u0930 \u0938\u0947 \u091c\u092e\u093e\u0928\u0947 \u0926\u0947\u0924\u093e \u0939\u0948 \u2014 \u092f\u0939\u0940 \u0935\u0939 \u0924\u0902\u0924\u094d\u0930 \u0939\u0948 \u091c\u093f\u0938\u0915\u0947 \u0938\u0939\u093e\u0930\u0947 \u0906\u092a \u0926\u094b \u0915\u093e\u092e\u094b\u0902 \u0915\u0947 \u092c\u0940\u091a \u091d\u0942\u0932\u0924\u0947 \u0939\u0941\u090f \u090f\u0915 \u0915\u094b \u092c\u093e\u0930-\u092c\u093e\u0930 \u091b\u094b\u0921\u093c\u0915\u0930 \u0926\u0942\u0938\u0930\u093e \u0909\u0920\u093e\u0924\u0947 \u0939\u0948\u0902\u0964",history:"\u092f\u0939 \u092a\u094d\u0930\u092d\u093e\u0935 \u0938\u092c\u0938\u0947 \u092a\u0939\u0932\u0947 1927 \u092e\u0947\u0902 Arthur Jersild \u0928\u0947 \u092c\u0924\u093e\u092f\u093e \u0925\u093e, \u091c\u093f\u0928\u094d\u0939\u094b\u0902\u0928\u0947 \u0932\u094b\u0917\u094b\u0902 \u0915\u094b \u092e\u093f\u0932\u0947-\u091c\u0941\u0932\u0947 \u0915\u093e\u092e\u094b\u0902 \u0915\u0940 \u090f\u0915 \u0938\u0942\u091a\u0940 \u092c\u0928\u093e\u092e \u090f\u0915 \u0939\u0940 \u092c\u093e\u0930-\u092c\u093e\u0930 \u0926\u094b\u0939\u0930\u093e\u090f \u091c\u093e\u0928\u0947 \u0935\u093e\u0932\u0947 \u0915\u093e\u092e \u092a\u0930 \u0926\u094c\u0921\u093c\u093e\u0915\u0930 \u0938\u092e\u092f \u092e\u093e\u092a\u093e \u0914\u0930 \u0926\u0947\u0916\u093e \u0915\u093f \u092e\u093f\u0932\u0940-\u091c\u0941\u0932\u0940 \u0938\u0942\u091a\u0940 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u092e\u0939\u0901\u0917\u0940 \u092a\u0921\u093c\u0924\u0940 \u0939\u0948\u0964 \u092f\u0939 \u0935\u093f\u091a\u093e\u0930 1990 \u0915\u0947 \u0926\u0936\u0915 \u0915\u0947 \u092e\u0927\u094d\u092f \u0924\u0915 \u0915\u093e\u092b\u093c\u0940 \u0939\u0926 \u0924\u0915 \u0926\u092c\u093e \u0930\u0939\u093e, \u091c\u092c \u0938\u0902\u091c\u094d\u091e\u093e\u0928\u093e\u0924\u094d\u092e\u0915-\u092e\u0928\u094b\u0935\u093f\u091c\u094d\u091e\u093e\u0928 \u0915\u0947 \u0915\u093e\u092e \u0915\u0940 \u090f\u0915 \u0932\u0939\u0930 \u0928\u0947 \u0907\u0938\u0947 \u0915\u093e\u0930\u094d\u092f\u0915\u093e\u0930\u0940-\u0928\u093f\u092f\u0902\u0924\u094d\u0930\u0923 \u0915\u0940 \u090f\u0915 \u0938\u093e\u092b\u093c \u0916\u093f\u0921\u093c\u0915\u0940 \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u092b\u093f\u0930 \u0938\u0947 \u091c\u093c\u093f\u0902\u0926\u093e \u0915\u0930 \u0926\u093f\u092f\u093e\u0964",creator:"\u0907\u0938 \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u093e \u0915\u094b\u0908 \u090f\u0915 \u0906\u0935\u093f\u0937\u094d\u0915\u093e\u0930\u0915 \u0928\u0939\u0940\u0902 \u0939\u0948\u0964 Arthur Jersild \u0928\u0947 1927 \u092e\u0947\u0902 \u092f\u0939 \u0924\u0941\u0932\u0928\u093e \u092a\u0947\u0936 \u0915\u0940, \u0914\u0930 \u0906\u0927\u0941\u0928\u093f\u0915 \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0915\u094b 1995 \u092e\u0947\u0902 Robert Rogers \u0914\u0930 Stephen Monsell \u0928\u0947 \u0906\u0915\u093e\u0930 \u0926\u093f\u092f\u093e, \u091c\u093f\u0928\u094d\u0939\u094b\u0902\u0928\u0947 switch cost \u0936\u092c\u094d\u0926 \u0917\u0922\u093c\u093e \u0914\u0930 \u0935\u094d\u092f\u093e\u092a\u0915 \u0930\u0942\u092a \u0938\u0947 \u0928\u0915\u093c\u0932 \u0915\u093f\u092f\u093e \u0917\u092f\u093e alternating-runs \u0922\u093e\u0901\u091a\u093e \u092c\u0928\u093e\u092f\u093e\u0964",methods:"\u0938\u0902\u0915\u0947\u0924 \u0915\u094b \u0938\u0902\u0915\u0947\u0924-\u0935\u0938\u094d\u0924\u0941 \u0926\u0947\u0916\u0928\u0947 \u0938\u0947 \u092a\u0939\u0932\u0947 \u092a\u0922\u093c\u0947\u0902, \u0914\u0930 \u092e\u094c\u091c\u0942\u0926\u093e \u0928\u093f\u092f\u092e \u0915\u094b \u0916\u093c\u0941\u0926 \u0938\u0947 \u0926\u094b\u0939\u0930\u093e\u090f\u0901 \u0924\u093e\u0915\u093f \u0917\u093c\u0932\u0924 \u0928\u093f\u092f\u092e \u0918\u0941\u0938 \u0928 \u0906\u090f\u0964 \u0905\u092a\u0928\u0940 \u0930\u092b\u093c\u094d\u0924\u093e\u0930 \u092c\u0938 \u0909\u0924\u0928\u0940 \u0939\u0940 \u092c\u0922\u093c\u093e\u090f\u0901 \u091c\u093f\u0924\u0928\u0940 \u0906\u092a\u0915\u0940 \u0938\u091f\u0940\u0915\u0924\u093e \u091d\u0947\u0932 \u0938\u0915\u0947, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u091c\u0932\u094d\u0926\u092c\u093e\u091c\u093c\u0940 switch cost \u0918\u091f\u093e\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u0917\u093c\u0932\u0924\u093f\u092f\u093e\u0901 \u092c\u0922\u093c\u093e\u0924\u0940 \u0939\u0948; \u0914\u0930 \u091c\u092c \u0906\u092a \u092a\u0939\u0932\u0947 \u0938\u0947 \u0924\u0948\u092f\u093e\u0930\u0940 \u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0930\u0928\u093e \u091a\u093e\u0939\u0947\u0902, \u0924\u094b \u0939\u0930 switch \u0938\u0947 \u092a\u0939\u0932\u0947 \u0915\u093e \u0905\u0902\u0924\u0930\u093e\u0932 \u0932\u0902\u092c\u093e \u0915\u0930 \u0932\u0947\u0902\u0964",duration:"\u091b\u094b\u091f\u0947, \u0915\u0947\u0902\u0926\u094d\u0930\u093f\u0924 \u092c\u094d\u0932\u0949\u0915 \u0938\u092c\u0938\u0947 \u0905\u091a\u094d\u091b\u0947 \u0930\u0939\u0924\u0947 \u0939\u0948\u0902 \u2014 \u090f\u0915 \u092c\u093e\u0930 \u092e\u0947\u0902 \u0915\u093c\u0930\u0940\u092c 5 \u0938\u0947 10 \u092e\u093f\u0928\u091f, \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u0915\u0941\u091b \u0926\u093f\u0928\u0964 switching \u092e\u093e\u0928\u0938\u093f\u0915 \u0930\u0942\u092a \u0938\u0947 \u0925\u0915\u093e \u0926\u0947\u0928\u0947 \u0935\u093e\u0932\u0940 \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0925\u0915\u0924\u0947 \u0939\u0940 \u0917\u0941\u0923\u0935\u0924\u094d\u0924\u093e \u0924\u0947\u091c\u093c\u0940 \u0938\u0947 \u0917\u093f\u0930\u0924\u0940 \u0939\u0948, \u0914\u0930 \u091a\u0941\u0938\u094d\u0924\u0940 \u0930\u0939\u0924\u0947 \u0930\u0941\u0915 \u091c\u093e\u0928\u093e \u090f\u0915 \u0932\u0902\u092c\u093e \u0938\u0924\u094d\u0930 \u0930\u0917\u0921\u093c\u0928\u0947 \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u0939\u0948\u0964",research:"\u091c\u094b \u092a\u0941\u0916\u093c\u094d\u0924\u093e \u0922\u0902\u0917 \u0938\u0947 \u0926\u093f\u0916\u093e \u0939\u0948 \u0935\u0939 \u0920\u0940\u0915 \u0935\u0939\u0940 \u0939\u0948 \u091c\u093f\u0938\u0915\u0940 \u0909\u092e\u094d\u092e\u0940\u0926 \u0939\u094b\u0917\u0940: switch cost \u090f\u0915 \u092e\u091c\u093c\u092c\u0942\u0924, \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u092a\u094d\u0930\u092d\u093e\u0935 \u0939\u0948, \u0914\u0930 \u0905\u092d\u094d\u092f\u093e\u0938 \u0938\u0947 \u0906\u092a switching \u091f\u093e\u0938\u094d\u0915 \u092e\u0947\u0902 \u0939\u0940 \u0924\u0947\u091c\u093c \u0914\u0930 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0938\u091f\u0940\u0915 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902\u0964 \u092c\u0921\u093c\u0947 \u0935\u093e\u0926\u0947 \u0915\u0939\u0940\u0902 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0921\u0917\u092e\u0917 \u0939\u0948\u0902, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0940 \u092e\u0932\u094d\u091f\u0940\u091f\u093e\u0938\u094d\u0915\u093f\u0902\u0917, \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u092c\u0941\u0926\u094d\u0927\u093f \u092f\u093e \u0909\u092e\u094d\u0930-\u091c\u0928\u093f\u0924 \u0917\u093f\u0930\u093e\u0935\u091f \u0938\u0947 \u092c\u091a\u093e\u0935 \u0924\u0915 \u0935\u094d\u092f\u093e\u092a\u0915 \u0938\u094d\u0925\u093e\u0928\u093e\u0902\u0924\u0930\u0923 \u0915\u092e\u091c\u093c\u094b\u0930 \u0914\u0930 \u0935\u093f\u0935\u093e\u0926\u093f\u0924 \u0939\u0948; \u0914\u0930 \u092c\u094d\u0930\u0947\u0928-\u091f\u094d\u0930\u0947\u0928\u093f\u0902\u0917 \u0915\u0940 \u0938\u092c\u0938\u0947 \u0938\u093e\u0935\u0927\u093e\u0928 \u0938\u092e\u0940\u0915\u094d\u0937\u093e\u090f\u0901, \u091c\u0948\u0938\u0947 2016 \u092e\u0947\u0902 Simons \u0914\u0930 \u0938\u093e\u0925\u093f\u092f\u094b\u0902 \u0915\u0940, \u092f\u0939 \u0928\u093f\u0937\u094d\u0915\u0930\u094d\u0937 \u0926\u0947\u0924\u0940 \u0939\u0948\u0902 \u0915\u093f far-transfer \u0915\u0947 \u0926\u093e\u0935\u0947 \u0915\u093e\u092b\u093c\u0940 \u0939\u0926 \u0924\u0915 \u092c\u0947\u0938\u0939\u093e\u0930\u093e \u0939\u0948\u0902 \u2014 \u0907\u0938\u0932\u093f\u090f \u0909\u0928\u094d\u0939\u0947\u0902 \u0938\u093e\u0935\u0927\u093e\u0928\u0940 \u0938\u0947 \u0932\u0947\u0902\u0964",rec:"\u0938\u0902\u0915\u0947\u0924 \u0915\u094b \u0939\u0940 \u0905\u0938\u0932\u0940 \u091f\u093e\u0938\u094d\u0915 \u0938\u092e\u091d\u0947\u0902: \u091c\u0935\u093e\u092c \u0926\u0947\u0928\u0947 \u0938\u0947 \u092a\u0939\u0932\u0947 \u090f\u0915 \u092a\u0932 \u0930\u0941\u0915\u0915\u0930 \u0928\u093f\u092f\u092e \u0915\u094b \u0926\u0930\u094d\u091c \u0915\u0930\u0947\u0902, \u0914\u0930 \u0906\u092a\u0915\u0940 \u0917\u093c\u0932\u0924\u0940-\u0926\u0930 \u0906\u092a\u0915\u0940 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0917\u0924\u093f \u0938\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0924\u0947\u091c\u093c\u0940 \u0938\u0947 \u0917\u093f\u0930\u0947\u0917\u0940\u0964",faq:[["\u0928\u093f\u092f\u092e \u092c\u0926\u0932\u0928\u0947 \u0915\u0947 \u0924\u0941\u0930\u0902\u0924 \u092c\u093e\u0926 \u092e\u0948\u0902 \u0927\u0940\u092e\u093e \u0915\u094d\u092f\u094b\u0902 \u092a\u0921\u093c \u091c\u093e\u0924\u093e \u0939\u0942\u0901?","\u0935\u0939 \u0927\u0940\u092e\u093e\u092a\u0928 \u0939\u0940 switch cost \u0939\u0948 \u2014 \u092f\u093e\u0928\u0940 \u092a\u0941\u0930\u093e\u0928\u093e \u0928\u093f\u092f\u092e \u091b\u094b\u0921\u093c\u0915\u0930 \u0928\u092f\u093e \u0932\u093e\u0926\u0928\u0947 \u092e\u0947\u0902 \u0906\u092a\u0915\u0947 \u0926\u093f\u092e\u093e\u0917\u093c \u0915\u094b \u0932\u0917\u0928\u0947 \u0935\u093e\u0932\u093e \u0938\u092e\u092f\u0964 \u092f\u0939 \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u0939\u0948 \u0914\u0930 \u0920\u0940\u0915 \u092f\u0939\u0940 \u091a\u0940\u091c\u093c \u092f\u0939 \u0905\u092d\u094d\u092f\u093e\u0938 \u092e\u093e\u092a\u0924\u093e \u0914\u0930 \u0938\u093e\u0927\u0924\u093e \u0939\u0948\u0964"],["\u0915\u094d\u092f\u093e \u0907\u0938\u0938\u0947 \u092e\u0948\u0902 \u0905\u0938\u0932 \u091c\u093c\u093f\u0902\u0926\u0917\u0940 \u092e\u0947\u0902 \u092e\u0932\u094d\u091f\u0940\u091f\u093e\u0938\u094d\u0915\u093f\u0902\u0917 \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u090a\u0901\u0917\u093e?","\u092f\u0939 \u0906\u092a\u0915\u094b \u0907\u0938 \u091f\u093e\u0938\u094d\u0915 \u092e\u0947\u0902 \u0924\u094b \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0922\u0902\u0917 \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u092c\u0928\u093e\u0924\u093e \u0939\u0948, \u092a\u0930 \u0907\u0938 \u092c\u093e\u0924 \u0915\u0947 \u0938\u092c\u0942\u0924 \u0915\u092e\u091c\u093c\u094b\u0930 \u0914\u0930 \u0935\u093f\u0935\u093e\u0926\u093f\u0924 \u0939\u0948\u0902 \u0915\u093f \u092f\u0939 \u0939\u0941\u0928\u0930 \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0940 \u092e\u0932\u094d\u091f\u0940\u091f\u093e\u0938\u094d\u0915\u093f\u0902\u0917 \u0924\u0915 \u092a\u0939\u0941\u0901\u091a\u0924\u093e \u0939\u0948\u0964 \u0907\u0938\u0947 \u0907\u0938\u0932\u093f\u090f \u0938\u093e\u0927\u0947\u0902 \u0915\u093f \u0905\u092d\u094d\u092f\u093e\u0938 \u092a\u0948\u0928\u093e \u0914\u0930 \u0926\u093f\u0932\u091a\u0938\u094d\u092a \u0939\u0948, \u0928 \u0915\u093f \u0935\u094d\u092f\u093e\u092a\u0915 \u0905\u0938\u0932-\u091c\u093c\u093f\u0902\u0926\u0917\u0940 \u0938\u094d\u0925\u093e\u0928\u093e\u0902\u0924\u0930\u0923 \u0915\u0947 \u0915\u093f\u0938\u0940 \u0935\u093e\u0926\u0947 \u092a\u0930\u0964"],["\u0915\u094d\u092f\u093e \u092e\u0941\u091d\u0947 \u0905\u0927\u093f\u0915\u0924\u092e \u0930\u092b\u093c\u094d\u0924\u093e\u0930 \u0915\u0947 \u0932\u093f\u090f \u091c\u093c\u094b\u0930 \u0932\u0917\u093e\u0928\u093e \u091a\u093e\u0939\u093f\u090f?","\u0928\u0939\u0940\u0902\u0964 \u0930\u092b\u093c\u094d\u0924\u093e\u0930 \u092c\u0938 \u0909\u0924\u0928\u0940 \u0939\u0940 \u092c\u0922\u093c\u093e\u090f\u0901 \u091c\u093f\u0924\u0928\u0940 \u0906\u092a\u0915\u0940 \u0938\u091f\u0940\u0915\u0924\u093e \u091d\u0947\u0932 \u0938\u0915\u0947\u0964 \u091c\u0932\u094d\u0926\u092c\u093e\u091c\u093c\u0940 \u091c\u093c\u094d\u092f\u093e\u0926\u093e\u0924\u0930 \u0917\u093c\u0932\u0924\u093f\u092f\u093e\u0901 \u0939\u0940 \u091c\u094b\u0921\u093c\u0924\u0940 \u0939\u0948, \u091c\u092c\u0915\u093f \u091c\u0935\u093e\u092c \u0926\u0947\u0928\u0947 \u0938\u0947 \u092a\u0939\u0932\u0947 \u0938\u0902\u0915\u0947\u0924 \u0915\u094b \u090f\u0915 \u092a\u0932 \u092a\u0922\u093c \u0932\u0947\u0928\u093e \u0939\u0940 \u0905\u0938\u0932 \u092e\u0947\u0902 switch cost \u0918\u091f\u093e\u0924\u093e \u0939\u0948\u0964"]],variants:"\u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0907\u0938 \u092c\u093e\u0924 \u0938\u0947 \u0905\u0932\u0917 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902 \u0915\u093f switch \u0915\u093e \u0938\u0902\u0915\u0947\u0924 \u0915\u0948\u0938\u0947 \u0926\u093f\u092f\u093e \u091c\u093e\u0924\u093e \u0939\u0948\u0964 alternating runs \u090f\u0915 \u0924\u092f \u092a\u0948\u091f\u0930\u094d\u0928 \u091c\u0948\u0938\u0947 AABB \u0915\u093e \u092a\u093e\u0932\u0928 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902 \u0924\u093e\u0915\u093f \u0906\u092a switch \u0915\u093e \u0905\u0902\u0926\u093e\u091c\u093c\u093e \u0932\u0917\u093e \u0938\u0915\u0947\u0902; explicit cueing \u0939\u0930 \u091f\u094d\u0930\u093e\u092f\u0932 \u092a\u0930 \u090f\u0915 \u091a\u093f\u0939\u094d\u0928 \u0926\u093f\u0916\u093e\u0924\u093e \u0939\u0948; \u0914\u0930 voluntary switching \u0906\u092a\u0915\u094b \u0916\u093c\u0941\u0926 \u0928\u093f\u092f\u092e \u091a\u0941\u0928\u0928\u0947 \u0926\u0947\u0924\u093e \u0939\u0948\u0964 \u0915\u0920\u093f\u0928\u093e\u0908 \u0928\u093f\u092f\u092e\u094b\u0902 \u0915\u0940 \u0938\u0902\u0916\u094d\u092f\u093e \u0914\u0930 \u0924\u0948\u092f\u093e\u0930\u0940 \u0915\u0947 \u0932\u093f\u090f \u092e\u093f\u0932\u0928\u0947 \u0935\u093e\u0932\u0947 \u0938\u092e\u092f \u0915\u0947 \u0938\u093e\u0925 \u092d\u0940 \u0918\u091f\u0924\u0940-\u092c\u0922\u093c\u0924\u0940 \u0939\u0948\u0964"},zh:{about:"\u4efb\u52a1\u5207\u6362\u4f1a\u7ed9\u4f60\u5448\u73b0\u4e00\u8fde\u4e32\u9879\u76ee\uff0c\u5e76\u4e0d\u65ad\u6539\u53d8\u4f60\u5fc5\u987b\u5957\u7528\u7684\u89c4\u5219\u3002\u8fd9\u4e00\u523b\u4f60\u6309\u5947\u5076\u6765\u7ed9\u4e00\u4e2a\u6570\u5b57\u5f52\u7c7b\uff0c\u4e0b\u4e00\u523b\u4e00\u4e2a\u7ebf\u7d22\u5c31\u628a\u4f60\u5207\u5230\u6309\u5927\u5c0f\u6765\u5f52\u7c7b\uff0c\u6240\u4ee5\u6bcf\u4e2a\u8bd5\u6b21\u4f60\u90fd\u8981\u8bfb\u7ebf\u7d22\u3001\u4e22\u6389\u65e7\u89c4\u5219\u3001\u88c5\u4e0a\u65b0\u89c4\u5219\uff0c\u5e76\u5728\u4e0d\u4e22\u51c6\u786e\u7387\u7684\u524d\u63d0\u4e0b\u5feb\u901f\u4f5c\u7b54\u3002",benefit:"\u5b83\u8bad\u7ec3\u8ba4\u77e5\u7075\u6d3b\u6027\uff0c\u4ee5\u53ca\u90a3\u79cd\u80fd\u6309\u9700\u91cd\u65b0\u914d\u7f6e\u5fc3\u7406\u5b9a\u52bf\u7684\u6267\u884c\u63a7\u5236\u2014\u2014\u8fd9\u6b63\u662f\u4f60\u6bcf\u5f53\u540c\u65f6\u517c\u987e\u4e24\u4ef6\u4e8b\u3001\u4e0d\u5f97\u4e0d\u653e\u4e0b\u4e00\u4ef6\u53bb\u62ff\u8d77\u53e6\u4e00\u4ef6\u65f6\u6240\u4f9d\u8d56\u7684\u90a3\u5957\u673a\u5236\u3002",history:"\u8fd9\u4e00\u6548\u5e94\u6700\u65e9\u7531 Arthur Jersild \u4e8e 1927 \u5e74\u62a5\u544a\uff0c\u4ed6\u7ed9\u4eba\u4eec\u8ba1\u65f6\uff0c\u6bd4\u8f83\u4ed6\u4eec\u8dd1\u4e00\u4efd\u6df7\u5408\u4efb\u52a1\u6e05\u5355\u4e0e\u4e00\u4efd\u5355\u4e00\u91cd\u590d\u4efb\u52a1\u6e05\u5355\u7684\u8017\u65f6\uff0c\u53d1\u73b0\u6df7\u5408\u6e05\u5355\u4ee3\u4ef7\u66f4\u9ad8\u3002\u8fd9\u4e2a\u60f3\u6cd5\u6b64\u540e\u5927\u4f53\u6c89\u5bc2\uff0c\u76f4\u5230 1990 \u5e74\u4ee3\u4e2d\u671f\uff0c\u4e00\u6ce2\u8ba4\u77e5\u5fc3\u7406\u5b66\u7684\u7814\u7a76\u628a\u5b83\u91cd\u65b0\u5524\u8d77\uff0c\u4f5c\u4e3a\u7aa5\u63a2\u6267\u884c\u63a7\u5236\u7684\u4e00\u6247\u5e72\u51c0\u7a97\u53e3\u3002",creator:"\u8fd9\u9879\u7ec3\u4e60\u6ca1\u6709\u5355\u4e00\u7684\u53d1\u660e\u8005\u3002Arthur Jersild \u4e8e 1927 \u5e74\u63d0\u51fa\u4e86\u8fd9\u79cd\u6bd4\u8f83\uff0c\u800c\u73b0\u4ee3\u7248\u672c\u7531 Robert Rogers \u548c Stephen Monsell \u4e8e 1995 \u5e74\u5851\u9020\uff0c\u4ed6\u4eec\u521b\u9020\u4e86\u201c\u5207\u6362\u4ee3\u4ef7\u201d\uff08switch cost\uff09\u4e00\u8bcd\uff0c\u5e76\u6784\u5efa\u4e86\u88ab\u5e7f\u6cdb\u4eff\u6548\u7684\u4ea4\u66ff\u5e8f\u5217\u8303\u5f0f\u3002",methods:"\u5728\u770b\u9879\u76ee\u4e4b\u524d\u5148\u8bfb\u7ebf\u7d22\uff0c\u5e76\u628a\u5f53\u524d\u89c4\u5219\u5728\u5fc3\u91cc\u5ff5\u51fa\u6765\uff0c\u4ee5\u514d\u9519\u8bef\u7684\u89c4\u5219\u6e17\u8fdb\u6765\u3002\u53ea\u628a\u901f\u5ea6\u63a8\u5230\u51c6\u786e\u7387\u8fd8\u6491\u5f97\u4f4f\u7684\u7a0b\u5ea6\uff0c\u56e0\u4e3a\u6c42\u5feb\u4f1a\u8ba9\u9519\u8bef\u589e\u591a\uff0c\u800c\u4e0d\u662f\u964d\u4f4e\u5207\u6362\u4ee3\u4ef7\uff1b\u5f53\u4f60\u60f3\u7ec3\u4e60\u63d0\u524d\u51c6\u5907\u65f6\uff0c\u5c31\u628a\u6bcf\u6b21\u5207\u6362\u524d\u7684\u95f4\u9694\u62c9\u957f\u4e00\u4e9b\u3002",duration:"\u77ed\u800c\u4e13\u6ce8\u7684\u65f6\u6bb5\u6548\u679c\u6700\u597d\uff0c\u5927\u7ea6\u6bcf\u6b21 5 \u5230 10 \u5206\u949f\u3001\u6bcf\u5468\u51e0\u5929\u3002\u5207\u6362\u5f88\u8d39\u8111\uff0c\u4e00\u65e6\u75b2\u52b3\uff0c\u8d28\u91cf\u5c31\u4f1a\u8fc5\u901f\u4e0b\u6ed1\uff0c\u6240\u4ee5\u8d81\u72b6\u6001\u8fd8\u597d\u65f6\u6536\u624b\uff0c\u80dc\u8fc7\u786c\u78e8\u4e00\u5927\u6bb5\u3002",research:"\u88ab\u624e\u5b9e\u8bc1\u660e\u7684\uff0c\u6070\u597d\u5c31\u662f\u4f60\u80fd\u6599\u5230\u7684\u90a3\u4e9b\uff1a\u5207\u6362\u4ee3\u4ef7\u662f\u4e00\u4e2a\u7a33\u5065\u3001\u53ef\u9760\u7684\u6548\u5e94\uff0c\u800c\u4e14\u901a\u8fc7\u7ec3\u4e60\uff0c\u4f60\u5728\u5207\u6362\u4efb\u52a1\u672c\u8eab\u4e0a\u4f1a\u53d8\u5f97\u66f4\u5feb\u3001\u66f4\u51c6\u3002\u66f4\u5927\u7684\u627f\u8bfa\u5219\u8981\u4e0d\u9760\u8c31\u5f97\u591a\uff0c\u56e0\u4e3a\u5411\u65e5\u5e38\u591a\u4efb\u52a1\u3001\u4e00\u822c\u667a\u529b\u6216\u5bf9\u6297\u5e74\u9f84\u76f8\u5173\u8870\u9000\u7684\u5bbd\u6cdb\u8fc1\u79fb\u65e2\u5f31\u53c8\u6709\u4e89\u8bae\uff1b\u800c\u6700\u4e25\u8c28\u7684\u8111\u529b\u8bad\u7ec3\u7efc\u8ff0\uff0c\u6bd4\u5982 Simons \u53ca\u540c\u4e8b 2016 \u5e74\u7684\u5de5\u4f5c\uff0c\u5f97\u51fa\u7684\u7ed3\u8bba\u662f\u8fdc\u8fc1\u79fb\u7684\u8bf4\u6cd5\u57fa\u672c\u5f97\u4e0d\u5230\u652f\u6301\uff0c\u6240\u4ee5\u5bf9\u5b83\u4eec\u8981\u4fdd\u6301\u8c28\u614e\u3002",rec:"\u628a\u7ebf\u7d22\u5f53\u4f5c\u771f\u6b63\u7684\u4efb\u52a1\uff1a\u4f5c\u7b54\u524d\u505c\u4e00\u62cd\u628a\u89c4\u5219\u8bb0\u7262\uff0c\u4f60\u7684\u9519\u8bef\u7387\u4f1a\u6bd4\u53cd\u5e94\u65f6\u4e0b\u964d\u5f97\u66f4\u5feb\u3002",faq:[["\u4e3a\u4ec0\u4e48\u89c4\u5219\u4e00\u53d8\u6211\u5c31\u6162\u4e0b\u6765\u4e86\uff1f","\u90a3\u79cd\u53d8\u6162\u5c31\u662f\u5207\u6362\u4ee3\u4ef7\uff0c\u4e5f\u5c31\u662f\u4f60\u7684\u5927\u8111\u4e22\u6389\u65e7\u89c4\u5219\u3001\u88c5\u4e0a\u65b0\u89c4\u5219\u6240\u9700\u7684\u65f6\u95f4\u3002\u5b83\u5f88\u6b63\u5e38\uff0c\u4e5f\u6b63\u662f\u8fd9\u9879\u7ec3\u4e60\u6240\u6d4b\u91cf\u548c\u8bad\u7ec3\u7684\u4e1c\u897f\u3002"],["\u8fd9\u4f1a\u8ba9\u6211\u5728\u73b0\u5b9e\u751f\u6d3b\u4e2d\u66f4\u64c5\u957f\u591a\u4efb\u52a1\u5904\u7406\u5417\uff1f","\u5b83\u4f1a\u53ef\u9760\u5730\u8ba9\u4f60\u66f4\u64c5\u957f\u8fd9\u9879\u4efb\u52a1\uff0c\u4f46\u8bf4\u8fd9\u79cd\u6280\u80fd\u80fd\u5e26\u5230\u65e5\u5e38\u591a\u4efb\u52a1\u5904\u7406\u4e0a\u7684\u8bc1\u636e\u65e2\u5f31\u53c8\u6709\u4e89\u8bae\u3002\u7ec3\u5b83\uff0c\u662f\u56e0\u4e3a\u8fd9\u79cd\u7ec3\u4e60\u654f\u9510\u800c\u6709\u5438\u5f15\u529b\uff0c\u800c\u4e0d\u662f\u51b2\u7740\u5bbd\u6cdb\u7684\u73b0\u5b9e\u8fc1\u79fb\u7684\u627f\u8bfa\u3002"],["\u6211\u5e94\u8be5\u8ffd\u6c42\u6781\u81f4\u7684\u901f\u5ea6\u5417\uff1f","\u4e0d\u3002\u53ea\u628a\u901f\u5ea6\u63a8\u5230\u51c6\u786e\u7387\u8fd8\u6491\u5f97\u4f4f\u7684\u7a0b\u5ea6\u3002\u6c42\u5feb\u591a\u534a\u53ea\u4f1a\u589e\u52a0\u9519\u8bef\uff0c\u800c\u4f5c\u7b54\u524d\u77ed\u6682\u5730\u8bfb\u4e00\u4e0b\u7ebf\u7d22\uff0c\u624d\u662f\u771f\u6b63\u80fd\u7f29\u5c0f\u5207\u6362\u4ee3\u4ef7\u7684\u505a\u6cd5\u3002"]],variants:"\u4e0d\u540c\u7248\u672c\u7684\u5dee\u522b\u5728\u4e8e\u5207\u6362\u662f\u5982\u4f55\u88ab\u63d0\u793a\u7684\u3002\u4ea4\u66ff\u5e8f\u5217\u9075\u5faa\u50cf AABB \u8fd9\u6837\u7684\u56fa\u5b9a\u6a21\u5f0f\uff0c\u6240\u4ee5\u4f60\u80fd\u9884\u6d4b\u5207\u6362\uff1b\u660e\u786e\u63d0\u793a\u5219\u6bcf\u4e2a\u8bd5\u6b21\u90fd\u7ed9\u51fa\u4e00\u4e2a\u7b26\u53f7\uff1b\u81ea\u4e3b\u5207\u6362\u5219\u8ba9\u4f60\u81ea\u5df1\u9009\u89c4\u5219\u3002\u96be\u5ea6\u8fd8\u4f1a\u968f\u89c4\u5219\u6570\u91cf\u548c\u4f60\u83b7\u5f97\u7684\u51c6\u5907\u65f6\u95f4\u800c\u53d8\u5316\u3002"}},targets:{ru:{about:"\xab\u0426\u0435\u043b\u0438: \u0440\u0435\u0430\u043a\u0446\u0438\u044f\xbb \u2014 \u044d\u0442\u043e \u043f\u0440\u043e\u0441\u0442\u043e\u0439 \u0442\u0435\u0441\u0442 \u043d\u0430 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u0440\u0435\u0430\u043a\u0446\u0438\u0438. \u0412\u044b \u0436\u0434\u0451\u0442\u0435 \u0441\u0438\u0433\u043d\u0430\u043b (\u043f\u043e\u044f\u0432\u0438\u043b\u0430\u0441\u044c \u0446\u0435\u043b\u044c \u0438\u043b\u0438 \u044d\u043a\u0440\u0430\u043d \u0441\u043c\u0435\u043d\u0438\u043b \u0446\u0432\u0435\u0442) \u0438 \u0436\u043c\u0451\u0442\u0435 \u043c\u0430\u043a\u0441\u0438\u043c\u0430\u043b\u044c\u043d\u043e \u0431\u044b\u0441\u0442\u0440\u043e, \u043d\u0435 \u0441\u0440\u044b\u0432\u0430\u044f\u0441\u044c \u0440\u0430\u043d\u044c\u0448\u0435 \u0432\u0440\u0435\u043c\u0435\u043d\u0438. \u0412\u0441\u044f \u0441\u0443\u0442\u044c \u2014 \u0438\u0437\u043c\u0435\u0440\u0438\u0442\u044c \u0438 \u0441\u043e\u043a\u0440\u0430\u0442\u0438\u0442\u044c \u043c\u0438\u043b\u043b\u0438\u0441\u0435\u043a\u0443\u043d\u0434\u044b \u043c\u0435\u0436\u0434\u0443 \xab\u0443\u0432\u0438\u0434\u0435\u043b\xbb \u0438 \xab\u043d\u0430\u0436\u0430\u043b\xbb.",benefit:"\u0422\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u043f\u0440\u043e\u0441\u0442\u043e\u0439 \u0440\u0435\u0430\u043a\u0446\u0438\u0438: \u043d\u0430\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0431\u044b\u0441\u0442\u0440\u043e \u0432\u044b \u0437\u0430\u043c\u0435\u0447\u0430\u0435\u0442\u0435 \u0441\u0438\u0433\u043d\u0430\u043b \u0438 \u0437\u0430\u043f\u0443\u0441\u043a\u0430\u0435\u0442\u0435 \u043e\u0434\u043d\u043e \u0437\u0430\u0440\u0430\u043d\u0435\u0435 \u0433\u043e\u0442\u043e\u0432\u043e\u0435 \u0434\u0432\u0438\u0436\u0435\u043d\u0438\u0435. \u0417\u0430\u043e\u0434\u043d\u043e \u043f\u043e\u0434\u0442\u044f\u0433\u0438\u0432\u0430\u0435\u0442 \u0433\u043e\u0442\u043e\u0432\u043d\u043e\u0441\u0442\u044c \u0434\u0435\u0439\u0441\u0442\u0432\u043e\u0432\u0430\u0442\u044c \u0438 \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044c \u0438\u043c\u043f\u0443\u043b\u044c\u0441\u0430 \u2014 \u043d\u0430\u0436\u0430\u0442\u0438\u0435 \u0434\u043e \u0441\u0438\u0433\u043d\u0430\u043b\u0430 \u0437\u0430\u0441\u0447\u0438\u0442\u044b\u0432\u0430\u0435\u0442\u0441\u044f \u043a\u0430\u043a \u043f\u0440\u043e\u043c\u0430\u0445.",history:"\u0418\u0437\u043c\u0435\u0440\u044f\u0442\u044c \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u0447\u0435\u043b\u043e\u0432\u0435\u0447\u0435\u0441\u043a\u043e\u0433\u043e \u043e\u0442\u043a\u043b\u0438\u043a\u0430 \u043d\u0430\u0447\u0430\u043b\u0438 \u0432 \u0430\u0441\u0442\u0440\u043e\u043d\u043e\u043c\u0438\u0438 XIX \u0432\u0435\u043a\u0430: \u043e\u043a\u043e\u043b\u043e 1822 \u0433\u043e\u0434\u0430 \u0424\u0440\u0438\u0434\u0440\u0438\u0445 \u0411\u0435\u0441\u0441\u0435\u043b\u044c \u0437\u0430\u043c\u0435\u0442\u0438\u043b, \u0447\u0442\u043e \u0440\u0430\u0437\u043d\u044b\u0435 \u043d\u0430\u0431\u043b\u044e\u0434\u0430\u0442\u0435\u043b\u0438 \u043f\u043e-\u0440\u0430\u0437\u043d\u043e\u043c\u0443 \u0444\u0438\u043a\u0441\u0438\u0440\u0443\u044e\u0442 \u043c\u043e\u043c\u0435\u043d\u0442 \u043f\u0440\u043e\u0445\u043e\u0436\u0434\u0435\u043d\u0438\u044f \u0437\u0432\u0435\u0437\u0434\u044b, \u2014 \u044d\u0442\u043e \u043d\u0430\u0437\u0432\u0430\u043b\u0438 \xab\u043b\u0438\u0447\u043d\u044b\u043c \u0443\u0440\u0430\u0432\u043d\u0435\u043d\u0438\u0435\u043c\xbb. \u0412 1850 \u0433\u043e\u0434\u0443 \u0413\u0435\u0440\u043c\u0430\u043d \u0444\u043e\u043d \u0413\u0435\u043b\u044c\u043c\u0433\u043e\u043b\u044c\u0446 \u0438\u0437\u043c\u0435\u0440\u0438\u043b \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u043d\u0435\u0440\u0432\u043d\u043e\u0433\u043e \u0441\u0438\u0433\u043d\u0430\u043b\u0430, \u0438 \u043c\u0435\u0442\u043e\u0434 \u043f\u0440\u0435\u0432\u0440\u0430\u0442\u0438\u043b\u0441\u044f \u0432 \u0438\u043d\u0441\u0442\u0440\u0443\u043c\u0435\u043d\u0442 \u044d\u043a\u0441\u043f\u0435\u0440\u0438\u043c\u0435\u043d\u0442\u0430\u043b\u044c\u043d\u043e\u0439 \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u0438. \u041f\u043e\u0437\u0436\u0435 \u043f\u0440\u043e\u0441\u0442\u043e\u0439 \u0442\u0435\u0441\u0442 \u043d\u0430 \u0440\u0435\u0430\u043a\u0446\u0438\u044e \u043f\u0440\u0438\u0436\u0438\u043b\u0441\u044f \u0432 \u043b\u0430\u0431\u043e\u0440\u0430\u0442\u043e\u0440\u0438\u044f\u0445, \u0441\u043f\u043e\u0440\u0442\u0438\u0432\u043d\u043e\u0439 \u043f\u043e\u0434\u0433\u043e\u0442\u043e\u0432\u043a\u0435 \u0438 \u0438\u0433\u0440\u0430\u0445.",creator:"\u0415\u0434\u0438\u043d\u043e\u0433\u043e \u0438\u0437\u043e\u0431\u0440\u0435\u0442\u0430\u0442\u0435\u043b\u044f \u0443 \u0442\u0435\u0441\u0442\u0430 \u043d\u0430 \u0440\u0435\u0430\u043a\u0446\u0438\u044e \u043d\u0435\u0442. \u041a\u043b\u044e\u0447\u0435\u0432\u0430\u044f \u0444\u0438\u0433\u0443\u0440\u0430 \u2014 \u0433\u043e\u043b\u043b\u0430\u043d\u0434\u0441\u043a\u0438\u0439 \u0444\u0438\u0437\u0438\u043e\u043b\u043e\u0433 \u0424\u0440\u0430\u043d\u0446\u0438\u0441\u043a \u041a\u043e\u0440\u043d\u0435\u043b\u0438\u0441 \u0414\u043e\u043d\u0434\u0435\u0440\u0441: \u0432 1868 \u0433\u043e\u0434\u0443 \u043e\u043d \u0444\u043e\u0440\u043c\u0430\u043b\u0438\u0437\u043e\u0432\u0430\u043b \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u043d\u0438\u0435 \u0432\u0440\u0435\u043c\u0435\u043d\u0438 \u0440\u0435\u0430\u043a\u0446\u0438\u0438 \u0434\u043b\u044f \u0438\u0437\u0443\u0447\u0435\u043d\u0438\u044f \u0440\u0430\u0431\u043e\u0442\u044b \u043f\u0441\u0438\u0445\u0438\u043a\u0438 (\u0442\u0430\u043a \u043d\u0430\u0437\u044b\u0432\u0430\u0435\u043c\u0430\u044f \u043c\u0435\u043d\u0442\u0430\u043b\u044c\u043d\u0430\u044f \u0445\u0440\u043e\u043d\u043e\u043c\u0435\u0442\u0440\u0438\u044f), \u043e\u043f\u0438\u0440\u0430\u044f\u0441\u044c \u043d\u0430 \u0430\u0441\u0442\u0440\u043e\u043d\u043e\u043c\u0438\u044e \u0411\u0435\u0441\u0441\u0435\u043b\u044f \u0438 \u0444\u0438\u0437\u0438\u043e\u043b\u043e\u0433\u0438\u044e \u0413\u0435\u043b\u044c\u043c\u0433\u043e\u043b\u044c\u0446\u0430. \u041f\u0440\u043e\u0441\u0442\u043e\u0439 \u0432\u0430\u0440\u0438\u0430\u043d\u0442 \xab\u043d\u0430\u0436\u043c\u0438 \u043f\u043e \u0441\u0438\u0433\u043d\u0430\u043b\u0443\xbb \u2014 \u044d\u0442\u043e \u043e\u0431\u0449\u0438\u0439 \u043d\u0430\u0443\u0447\u043d\u044b\u0439 \u043c\u0435\u0442\u043e\u0434, \u0430 \u043d\u0435 \u0447\u044c\u0451-\u0442\u043e \u0444\u0438\u0440\u043c\u0435\u043d\u043d\u043e\u0435 \u0438\u0437\u043e\u0431\u0440\u0435\u0442\u0435\u043d\u0438\u0435.",methods:"\u0423\u0431\u0435\u0440\u0438\u0442\u0435 \u043e\u0442\u0432\u043b\u0435\u043a\u0430\u044e\u0449\u0438\u0435 \u0444\u0430\u043a\u0442\u043e\u0440\u044b, \u0434\u0435\u0440\u0436\u0438\u0442\u0435 \u0440\u0443\u043a\u0443 \u0440\u0430\u0441\u0441\u043b\u0430\u0431\u043b\u0435\u043d\u043d\u043e\u0439 \u0438 \u0432 \u043e\u0434\u043d\u043e\u0439 \u0438 \u0442\u043e\u0439 \u0436\u0435 \u0442\u043e\u0447\u043a\u0435 \u043d\u0430 \u043a\u0430\u0436\u0434\u043e\u0439 \u043f\u043e\u043f\u044b\u0442\u043a\u0435. \u0421\u043b\u0435\u0434\u0438\u0442\u0435 \u0437\u0430 \u0441\u0438\u0433\u043d\u0430\u043b\u043e\u043c, \u043d\u043e \u043d\u0435 \u043f\u044b\u0442\u0430\u0439\u0442\u0435\u0441\u044c \u0435\u0433\u043e \u0443\u0433\u0430\u0434\u0430\u0442\u044c \u2014 \u043f\u0440\u0435\u0434\u0443\u0433\u0430\u0434\u044b\u0432\u0430\u043d\u0438\u0435 \u0432\u0435\u0434\u0451\u0442 \u043a \u0444\u0430\u043b\u044c\u0441\u0442\u0430\u0440\u0442\u0430\u043c, \u0430 \u043d\u0435 \u043a \u043b\u0443\u0447\u0448\u0435\u043c\u0443 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442\u0443. \u0414\u0435\u043b\u0430\u0439\u0442\u0435 \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u0435 \u0441\u0435\u0440\u0438\u0438 \u0438\u0437 \u043c\u043d\u043e\u0436\u0435\u0441\u0442\u0432\u0430 \u043f\u043e\u043f\u044b\u0442\u043e\u043a, \u0430 \u043d\u0435 \u043f\u0430\u0440\u0443 \u043d\u0435\u0440\u0432\u043d\u044b\u0445 \u043d\u0430\u0436\u0430\u0442\u0438\u0439, \u0438 \u0441\u043c\u043e\u0442\u0440\u0438\u0442\u0435 \u043d\u0430 \u0441\u0440\u0435\u0434\u043d\u0438\u0439 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442 \u0438 \u043d\u0430 \u0441\u0430\u043c\u044b\u0435 \u043c\u0435\u0434\u043b\u0435\u043d\u043d\u044b\u0435 \u043e\u0442\u043a\u043b\u0438\u043a\u0438, \u0430 \u043d\u0435 \u0442\u043e\u043b\u044c\u043a\u043e \u043d\u0430 \u043b\u0443\u0447\u0448\u0438\u0439 \u0441\u043b\u0443\u0447\u0430\u0439\u043d\u044b\u0439.",duration:"\u0420\u0435\u0430\u043a\u0446\u0438\u044f \u0447\u0443\u0432\u0441\u0442\u0432\u0438\u0442\u0435\u043b\u044c\u043d\u0430 \u043a \u0443\u0441\u0442\u0430\u043b\u043e\u0441\u0442\u0438, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u0434\u0435\u0440\u0436\u0438\u0442\u0435 \u043a\u043e\u0440\u043e\u0442\u043a\u043e: 2-5 \u043c\u0438\u043d\u0443\u0442 \u0441\u043e\u0441\u0440\u0435\u0434\u043e\u0442\u043e\u0447\u0435\u043d\u043d\u044b\u0445 \u043f\u043e\u043f\u044b\u0442\u043e\u043a \u0440\u0430\u0437 \u0432 \u0434\u0435\u043d\u044c \u0431\u043e\u043b\u0435\u0435 \u0447\u0435\u043c \u0434\u043e\u0441\u0442\u0430\u0442\u043e\u0447\u043d\u043e. \u041a\u043e\u0440\u043e\u0442\u043a\u0438\u0435 \u0447\u0430\u0441\u0442\u044b\u0435 \u043f\u043e\u0434\u0445\u043e\u0434\u044b \u043b\u0443\u0447\u0448\u0435 \u0434\u043b\u0438\u043d\u043d\u044b\u0445, \u0430 \u0446\u0438\u0444\u0440\u044b \u043f\u0440\u043e\u0441\u044f\u0434\u0443\u0442, \u043a\u0430\u043a \u0442\u043e\u043b\u044c\u043a\u043e \u0432\u044b \u0443\u0441\u0442\u0430\u043b\u0438, \u043d\u0435 \u0432\u044b\u0441\u043f\u0430\u043b\u0438\u0441\u044c \u0438\u043b\u0438 \u043e\u0442\u0432\u043b\u0435\u043a\u043b\u0438\u0441\u044c.",research:"\u041d\u0430\u0434\u0451\u0436\u043d\u043e \u0434\u043e\u043a\u0430\u0437\u0430\u043d\u043e \u043d\u0435\u043c\u043d\u043e\u0433\u043e\u0435: \u0441 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u043e\u0439 \u0432\u044b \u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u0435\u0441\u044c \u0437\u0430\u043c\u0435\u0442\u043d\u043e \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u0438 \u0441\u0442\u0430\u0431\u0438\u043b\u044c\u043d\u0435\u0435 \u0438\u043c\u0435\u043d\u043d\u043e \u0432 \u044d\u0442\u043e\u043c \u0437\u0430\u0434\u0430\u043d\u0438\u0438 \u2014 \u0432 \u043e\u0441\u043d\u043e\u0432\u043d\u043e\u043c \u0437\u0430 \u0441\u0447\u0451\u0442 \u0442\u043e\u0433\u043e, \u0447\u0442\u043e \u0443\u0445\u043e\u0434\u044f\u0442 \u0444\u0430\u043b\u044c\u0441\u0442\u0430\u0440\u0442\u044b \u0438 \u043f\u0440\u043e\u0432\u0430\u043b\u044b \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f. \u041d\u043e \u0432\u0430\u0448 \u043f\u0440\u0435\u0434\u0435\u043b \u0432\u043e \u043c\u043d\u043e\u0433\u043e\u043c \u0437\u0430\u0434\u0430\u043d \u0444\u0438\u0437\u0438\u043e\u043b\u043e\u0433\u0438\u0435\u0439 \u043d\u0435\u0440\u0432\u043d\u043e\u0439 \u0441\u0438\u0441\u0442\u0435\u043c\u044b (\u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u043f\u0440\u043e\u0432\u0435\u0434\u0435\u043d\u0438\u044f \u0441\u0438\u0433\u043d\u0430\u043b\u0430 \u0438 \u043e\u0431\u0440\u0430\u0431\u043e\u0442\u043a\u0438), \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u0437\u0434\u043e\u0440\u043e\u0432\u044b\u0439 \u0432\u0437\u0440\u043e\u0441\u043b\u044b\u0439 \u0434\u0435\u0440\u0436\u0438\u0442\u0441\u044f \u043e\u043a\u043e\u043b\u043e 200-250 \u043c\u0441 \u0438 \u043d\u0435 \u043c\u043e\u0436\u0435\u0442 \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u043e\u0439 \u043e\u043f\u0443\u0441\u043a\u0430\u0442\u044c \u044d\u0442\u043e \u0431\u0435\u0437 \u043a\u043e\u043d\u0446\u0430. \u0423\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043d\u0438\u044f, \u0447\u0442\u043e \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0430 \u0440\u0435\u0430\u043a\u0446\u0438\u0438 \u0432 \u0446\u0435\u043b\u043e\u043c \xab\u043f\u0440\u043e\u043a\u0430\u0447\u0438\u0432\u0430\u0435\u0442 \u043c\u043e\u0437\u0433\xbb, \u043f\u043e\u0434\u043d\u0438\u043c\u0430\u0435\u0442 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0438\u043b\u0438 \u043f\u0440\u0435\u0434\u043e\u0442\u0432\u0440\u0430\u0449\u0430\u0435\u0442 \u0432\u043e\u0437\u0440\u0430\u0441\u0442\u043d\u043e\u0439 \u0441\u043f\u0430\u0434, \u0441\u043b\u0430\u0431\u043e \u043e\u0431\u043e\u0441\u043d\u043e\u0432\u0430\u043d\u044b: \u043f\u0435\u0440\u0435\u043d\u043e\u0441 \u0437\u0430 \u043f\u0440\u0435\u0434\u0435\u043b\u044b \u0441\u0430\u043c\u043e\u0433\u043e \u0437\u0430\u0434\u0430\u043d\u0438\u044f \u2014 \u0441\u043a\u043e\u0440\u0435\u0435 \u0438\u0441\u043a\u043b\u044e\u0447\u0435\u043d\u0438\u0435, \u0447\u0435\u043c \u043f\u0440\u0430\u0432\u0438\u043b\u043e. \u0410 \u0432\u0430\u0448 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442 \u0437\u0430 \u0434\u0435\u043d\u044c \u2014 \u0435\u0449\u0451 \u0438 \u0447\u0443\u0432\u0441\u0442\u0432\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0439 \u0438\u043d\u0434\u0438\u043a\u0430\u0442\u043e\u0440 \u0441\u043d\u0430, \u0431\u043e\u0434\u0440\u043e\u0441\u0442\u0438 \u0438 \u0443\u0442\u043e\u043c\u043b\u0435\u043d\u0438\u044f.",rec:"\u0421\u0447\u0438\u0442\u0430\u0439\u0442\u0435 \u043d\u0430\u0441\u0442\u043e\u044f\u0449\u0438\u043c \u043f\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u0435\u043c \u0441\u0440\u0435\u0434\u043d\u0438\u0439 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442 \u043f\u043e \u043c\u043d\u043e\u0433\u0438\u043c \u043f\u043e\u043f\u044b\u0442\u043a\u0430\u043c, \u0430 \u043f\u043b\u043e\u0445\u043e\u0439 \u0434\u0435\u043d\u044c \u0432\u043e\u0441\u043f\u0440\u0438\u043d\u0438\u043c\u0430\u0439\u0442\u0435 \u043a\u0430\u043a \u043f\u043e\u0432\u043e\u0434 \u043f\u0440\u043e\u0432\u0435\u0440\u0438\u0442\u044c \u0441\u043e\u043d, \u0430 \u043d\u0435 \u043a\u0430\u043a \u0441\u0438\u0433\u043d\u0430\u043b \xab\u0434\u0430\u0432\u0438\u0442\u044c \u0441\u0438\u043b\u044c\u043d\u0435\u0435\xbb.",faq:[["\u041c\u043e\u0436\u043d\u043e \u043b\u0438 \u0440\u0435\u0430\u043b\u044c\u043d\u043e \u0443\u0441\u043a\u043e\u0440\u0438\u0442\u044c \u0441\u0432\u043e\u044e \u0440\u0435\u0430\u043a\u0446\u0438\u044e?","\u0414\u0430, \u043d\u043e \u0432 \u043f\u0440\u0435\u0434\u0435\u043b\u0430\u0445. \u041f\u0440\u0430\u043a\u0442\u0438\u043a\u0430 \u0443\u0431\u0438\u0440\u0430\u0435\u0442 \u0444\u0430\u043b\u044c\u0441\u0442\u0430\u0440\u0442\u044b \u0438 \u043f\u0440\u043e\u0432\u0430\u043b\u044b, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u0441\u0440\u0435\u0434\u043d\u0438\u0439 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442 \u0443\u043b\u0443\u0447\u0448\u0430\u0435\u0442\u0441\u044f, \u043d\u043e \u0441\u0430\u043c\u044b\u0439 \u0431\u044b\u0441\u0442\u0440\u044b\u0439 \u0432\u043e\u0437\u043c\u043e\u0436\u043d\u044b\u0439 \u043e\u0442\u043a\u043b\u0438\u043a \u0432 \u043e\u0441\u043d\u043e\u0432\u043d\u043e\u043c \u043e\u0433\u0440\u0430\u043d\u0438\u0447\u0435\u043d \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c\u044e \u0440\u0430\u0431\u043e\u0442\u044b \u043d\u0435\u0440\u0432\u043e\u0432 \u0438 \u043c\u043e\u0437\u0433\u0430, \u0438 \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u043e\u0439 \u0435\u0433\u043e \u043d\u0435 \u0441\u043d\u0438\u0437\u0438\u0442\u044c \u0431\u0435\u0441\u043a\u043e\u043d\u0435\u0447\u043d\u043e."],["\u041a\u0430\u043a\u043e\u0435 \u0432\u0440\u0435\u043c\u044f \u043f\u0440\u043e\u0441\u0442\u043e\u0439 \u0440\u0435\u0430\u043a\u0446\u0438\u0438 \u0441\u0447\u0438\u0442\u0430\u0435\u0442\u0441\u044f \u0445\u043e\u0440\u043e\u0448\u0438\u043c?","\u0423 \u0437\u0434\u043e\u0440\u043e\u0432\u043e\u0433\u043e \u0432\u0437\u0440\u043e\u0441\u043b\u043e\u0433\u043e \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u0430\u044f \u043f\u0440\u043e\u0441\u0442\u0430\u044f \u0440\u0435\u0430\u043a\u0446\u0438\u044f \u0434\u0435\u0440\u0436\u0438\u0442\u0441\u044f \u043f\u0440\u0438\u043c\u0435\u0440\u043d\u043e \u0432 \u0440\u0430\u0439\u043e\u043d\u0435 200-250 \u043c\u0441. \u041a \u043b\u044e\u0431\u043e\u0439 \u043e\u0434\u043d\u043e\u0439 \u0446\u0438\u0444\u0440\u0435 \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u0435\u0441\u044c \u043e\u0441\u0442\u043e\u0440\u043e\u0436\u043d\u043e: \u0443\u0441\u0442\u0430\u043b\u043e\u0441\u0442\u044c, \u0441\u043e\u043d, \u043a\u043e\u0444\u0435\u0438\u043d \u0438 \u0441\u0430\u043c\u043e \u0443\u0441\u0442\u0440\u043e\u0439\u0441\u0442\u0432\u043e \u0437\u0430\u043c\u0435\u0442\u043d\u043e \u0435\u0451 \u0441\u0434\u0432\u0438\u0433\u0430\u044e\u0442."],["\u0421\u0434\u0435\u043b\u0430\u0435\u0442 \u043b\u0438 \u044d\u0442\u043e \u043c\u0435\u043d\u044f \u0443\u043c\u043d\u0435\u0435 \u0438\u043b\u0438 \u043b\u0443\u0447\u0448\u0438\u043c \u0432\u043e\u0434\u0438\u0442\u0435\u043b\u0435\u043c?","\u041d\u0435 \u0440\u0430\u0441\u0441\u0447\u0438\u0442\u044b\u0432\u0430\u0439\u0442\u0435 \u043d\u0430 \u0448\u0438\u0440\u043e\u043a\u0438\u0439 \u043f\u0435\u0440\u0435\u043d\u043e\u0441. \u0412 \u044d\u0442\u043e\u043c \u0437\u0430\u0434\u0430\u043d\u0438\u0438 \u0432\u044b \u0441\u0442\u0430\u043d\u0435\u0442\u0435 \u0431\u044b\u0441\u0442\u0440\u0435\u0435, \u043d\u043e \u0434\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432\u0430 \u0442\u043e\u0433\u043e, \u0447\u0442\u043e \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0430 \u0440\u0435\u0430\u043a\u0446\u0438\u0438 \u043f\u043e\u0432\u044b\u0448\u0430\u0435\u0442 \u043e\u0431\u0449\u0438\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0438\u043b\u0438 \u0440\u0435\u0430\u043b\u044c\u043d\u044b\u0435 \u043d\u0430\u0432\u044b\u043a\u0438 \u0432\u0440\u043e\u0434\u0435 \u0432\u043e\u0436\u0434\u0435\u043d\u0438\u044f, \u0441\u043b\u0430\u0431\u044b \u2014 \u043e\u0446\u0435\u043d\u0438\u0432\u0430\u0439\u0442\u0435 \u044d\u0442\u043e \u043a\u0430\u043a \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0443 \u0440\u0435\u0430\u043a\u0446\u0438\u0438, \u0430 \u043d\u0435 \u0430\u043f\u0433\u0440\u0435\u0439\u0434 \u043c\u043e\u0437\u0433\u0430."]],variants:"\u0421\u0440\u0435\u0434\u0438 \u0432\u0430\u0440\u0438\u0430\u0446\u0438\u0439: \u0440\u0435\u0430\u043a\u0446\u0438\u044f \u0432\u044b\u0431\u043e\u0440\u0430 (\u0432\u044b\u0431\u0440\u0430\u0442\u044c \u043d\u0443\u0436\u043d\u044b\u0439 \u043e\u0442\u0432\u0435\u0442 \u0441\u0440\u0435\u0434\u0438 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u0438\u0445 \u0446\u0435\u043b\u0435\u0439), \u0437\u0430\u0434\u0430\u0447\u0438 go/no-go (\u043d\u0430 \u043e\u0434\u043d\u0438 \u0441\u0438\u0433\u043d\u0430\u043b\u044b \u0440\u0435\u0430\u0433\u0438\u0440\u043e\u0432\u0430\u0442\u044c, \u043d\u0430 \u0434\u0440\u0443\u0433\u0438\u0435 \u2014 \u0441\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0442\u044c\u0441\u044f), \u0437\u0432\u0443\u043a\u043e\u0432\u043e\u0439 \u0441\u0438\u0433\u043d\u0430\u043b \u0432\u043c\u0435\u0441\u0442\u043e \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u0433\u043e, \u0430 \u0442\u0430\u043a\u0436\u0435 \u0432\u0435\u0440\u0441\u0438\u0438 \xab\u043f\u043e\u043f\u0430\u0434\u0438 \u043f\u043e \u0446\u0435\u043b\u0438\xbb, \u0433\u0434\u0435 \u043c\u0438\u0448\u0435\u043d\u044c \u0435\u0449\u0451 \u0438 \u0434\u0432\u0438\u0436\u0435\u0442\u0441\u044f, \u0434\u043e\u0431\u0430\u0432\u043b\u044f\u044f \u044d\u043b\u0435\u043c\u0435\u043d\u0442 \u043f\u0440\u0438\u0446\u0435\u043b\u0438\u0432\u0430\u043d\u0438\u044f."},en:{about:"Targets: Reaction is a simple reaction-time task. You wait for the signal \u2014 a target appears or the screen changes colour \u2014 and tap as fast as you possibly can, without jumping the gun before the cue. The whole point is to measure and shave milliseconds off the gap between seeing and acting.",benefit:"It trains the speed of your simple reaction: how quickly you detect a stimulus and fire off a single, pre-planned motor response. It also sharpens your readiness to act and your impulse control, since reacting before the signal counts as a miss.",history:"Measuring human response speed grew out of 19th-century astronomy, where Friedrich Bessel noticed around 1822 that different observers timed star transits differently \u2014 the 'personal equation'. Hermann von Helmholtz then measured nerve-signal speed in 1850, and the method matured into a tool of experimental psychology. From there the simple-reaction test became a lab staple and, much later, a fixture of sports training, driving research and gaming.",creator:"There is no single inventor of the reaction-time task. The Dutch physiologist Franciscus Cornelis Donders is the key pioneer: in 1868 he formalised the use of reaction times to study mental processes (mental chronometry), building on Bessel's astronomy and Helmholtz's physiology. The plain tap-on-signal version is a generic experimental method, not a branded game.",methods:"Eliminate distractions and keep your hand relaxed and resting in the same spot every trial. Watch for the signal but resist the urge to anticipate it \u2014 predicting the timing leads to false starts, not faster scores. Run short blocks of many trials rather than a few tense attempts, and track your average and your slowest reactions, not just your best fluke.",duration:"Reaction is fatigue-sensitive, so keep it brief: 2-5 minutes of focused trials, once a day, is plenty. Short, frequent sessions beat long ones, and your numbers will sag the moment you are tired, sleepy, or distracted.",research:"What is solidly shown is narrow: with practice you get measurably faster and more consistent at this exact task, mostly by cutting false starts and lapses. Your floor, though, is largely set by neurophysiology \u2014 nerve conduction and processing speed \u2014 so a healthy adult sits near 200-250 ms and cannot train that down without limit. Claims that reaction drills broadly sharpen the mind, raise intelligence, or prevent cognitive decline are weak and largely unproven; transfer beyond the trained task is the exception, not the rule. Your daily score is also a sensitive readout of sleep, alertness and fatigue.",rec:"Treat your average over many trials as the real measure, and use a bad day as a signal to check your sleep rather than to grind harder.",faq:[["Can I really make my reaction time faster?","Yes, but within limits. Practice trims false starts and lapses so your average improves, yet your fastest possible response is mostly capped by nerve and brain processing speed, which training cannot lower indefinitely."],["What is a good simple reaction time?","For a healthy adult a visual simple reaction lands roughly around 200-250 ms. Treat any single number cautiously \u2014 fatigue, sleep, caffeine and the device you use all shift it."],["Will this make me smarter or a better driver?","Don't count on broad carry-over. You will get faster at this task, but evidence that reaction drills boost general intelligence or real-world skills like driving is weak, so judge it as reaction practice, not a brain upgrade."]],variants:"Variations include choice reaction time (pick the right response among several targets), go/no-go tasks (act on some cues, withhold on others), audio instead of visual signals, and 'whack-the-target' versions where the target also moves, adding an aiming component."},es:{about:"Targets: Reaction es una tarea sencilla de tiempo de reacci\xf3n. Esperas la se\xf1al \u2014aparece un objetivo o la pantalla cambia de color\u2014 y tocas lo m\xe1s r\xe1pido que puedas, sin adelantarte antes de la se\xf1al. Toda la gracia est\xe1 en medir y recortar milisegundos del lapso entre ver y actuar.",benefit:"Entrena la velocidad de tu reacci\xf3n simple: con qu\xe9 rapidez detectas un est\xedmulo y disparas una \xfanica respuesta motora preparada de antemano. Tambi\xe9n afina tu disposici\xf3n a actuar y tu control de impulsos, ya que reaccionar antes de la se\xf1al cuenta como fallo.",history:"La medici\xf3n de la velocidad de respuesta humana surgi\xf3 de la astronom\xeda del siglo XIX, donde Friedrich Bessel not\xf3 hacia 1822 que distintos observadores cronometraban de forma diferente el tr\xe1nsito de las estrellas: la 'ecuaci\xf3n personal'. Hermann von Helmholtz midi\xf3 despu\xe9s la velocidad de la se\xf1al nerviosa en 1850, y el m\xe9todo madur\xf3 hasta convertirse en una herramienta de la psicolog\xeda experimental. De ah\xed, la prueba de reacci\xf3n simple pas\xf3 a ser un elemento b\xe1sico del laboratorio y, mucho despu\xe9s, un componente fijo del entrenamiento deportivo, la investigaci\xf3n sobre conducci\xf3n y los videojuegos.",creator:"No hay un \xfanico inventor de la tarea de tiempo de reacci\xf3n. El fisi\xf3logo neerland\xe9s Franciscus Cornelis Donders es el pionero clave: en 1868 formaliz\xf3 el uso de los tiempos de reacci\xf3n para estudiar los procesos mentales (cronometr\xeda mental), apoy\xe1ndose en la astronom\xeda de Bessel y la fisiolog\xeda de Helmholtz. La versi\xf3n llana de tocar-ante-la-se\xf1al es un m\xe9todo experimental gen\xe9rico, no un juego de marca.",methods:"Elimina las distracciones y mant\xe9n la mano relajada y apoyada en el mismo sitio en cada intento. Vigila la se\xf1al pero resiste el impulso de anticiparla: predecir el momento lleva a salidas en falso, no a mejores marcas. Haz bloques cortos de muchos intentos en lugar de unos pocos intentos tensos, y f\xedjate en tu media y en tus reacciones m\xe1s lentas, no solo en tu mejor golpe de suerte.",duration:"La reacci\xf3n es sensible a la fatiga, as\xed que mantenlo breve: de 2 a 5 minutos de intentos concentrados, una vez al d\xeda, basta. Las sesiones cortas y frecuentes ganan a las largas, y tus n\xfameros se desplomar\xe1n en cuanto est\xe9s cansado, somnoliento o distra\xeddo.",research:"Lo s\xf3lido es concreto: con la pr\xe1ctica te vuelves de forma medible m\xe1s r\xe1pido y constante en esta tarea exacta, sobre todo recortando salidas en falso y despistes. Tu suelo, sin embargo, lo fija en gran parte la neurofisiolog\xeda \u2014la conducci\xf3n nerviosa y la velocidad de procesamiento\u2014, as\xed que un adulto sano se sit\xfaa cerca de los 200-250 ms y no puede entrenarlo a la baja sin l\xedmite. Las afirmaciones de que los ejercicios de reacci\xf3n afinan ampliamente la mente, elevan la inteligencia o previenen el declive cognitivo son d\xe9biles y en gran medida sin demostrar; la transferencia m\xe1s all\xe1 de la tarea entrenada es la excepci\xf3n, no la regla. Tu marca diaria es adem\xe1s un indicador sensible del sue\xf1o, el estado de alerta y la fatiga.",rec:"Toma tu media a lo largo de muchos intentos como la verdadera medida, y usa un mal d\xeda como se\xf1al para revisar tu sue\xf1o en lugar de para machacar m\xe1s.",faq:[["\xbfDe verdad puedo hacer m\xe1s r\xe1pido mi tiempo de reacci\xf3n?","S\xed, pero dentro de unos l\xedmites. La pr\xe1ctica recorta las salidas en falso y los despistes, as\xed que tu media mejora, pero tu respuesta m\xe1s r\xe1pida posible est\xe1 en gran parte limitada por la velocidad de procesamiento nervioso y cerebral, que el entrenamiento no puede rebajar indefinidamente."],["\xbfCu\xe1l es un buen tiempo de reacci\xf3n simple?","Para un adulto sano, una reacci\xf3n visual simple ronda los 200-250 ms. Toma con cautela cualquier cifra aislada: la fatiga, el sue\xf1o, la cafe\xedna y el dispositivo que uses la desplazan todos."],["\xbfEsto me har\xe1 m\xe1s inteligente o mejor conductor?","No cuentes con una transferencia amplia. Mejorar\xe1s en esta tarea, pero la evidencia de que los ejercicios de reacci\xf3n potencien la inteligencia general o habilidades reales como conducir es d\xe9bil, as\xed que val\xf3ralo como pr\xe1ctica de reacci\xf3n, no como una mejora cerebral."]],variants:"Las variantes incluyen el tiempo de reacci\xf3n de elecci\xf3n (escoger la respuesta correcta entre varios objetivos), las tareas go/no-go (actuar ante unas se\xf1ales, contenerse ante otras), se\xf1ales sonoras en lugar de visuales y versiones de 'golpea el objetivo' en las que el objetivo adem\xe1s se mueve, a\xf1adiendo un componente de punter\xeda."},de:{about:"Targets: Reaction ist eine einfache Reaktionszeitaufgabe. Du wartest auf das Signal \u2014 ein Ziel erscheint oder der Bildschirm wechselt die Farbe \u2014 und tippst so schnell du nur kannst, ohne vor dem Reiz loszupreschen. Der ganze Sinn besteht darin, die Spanne zwischen Sehen und Handeln zu messen und um Millisekunden zu verk\xfcrzen.",benefit:"Sie trainiert die Geschwindigkeit deiner einfachen Reaktion: wie schnell du einen Reiz wahrnimmst und eine einzelne, vorgeplante motorische Antwort abfeuerst. Sie sch\xe4rft auch deine Handlungsbereitschaft und deine Impulskontrolle, denn vor dem Signal zu reagieren gilt als Fehlversuch.",history:"Das Messen menschlicher Reaktionsgeschwindigkeit entwuchs der Astronomie des 19. Jahrhunderts, wo Friedrich Bessel um 1822 bemerkte, dass verschiedene Beobachter Sterndurchg\xe4nge unterschiedlich stoppten \u2014 die 'pers\xf6nliche Gleichung'. Hermann von Helmholtz ma\xdf dann 1850 die Geschwindigkeit von Nervensignalen, und die Methode reifte zu einem Werkzeug der experimentellen Psychologie. Von dort wurde der einfache Reaktionstest zum festen Bestandteil des Labors und, viel sp\xe4ter, des Sporttrainings und trieb Forschung und Spiele an.",creator:"Es gibt keinen einzelnen Erfinder der Reaktionszeitaufgabe. Der niederl\xe4ndische Physiologe Franciscus Cornelis Donders ist der entscheidende Wegbereiter: 1868 formalisierte er den Einsatz von Reaktionszeiten zur Untersuchung geistiger Vorg\xe4nge (mentale Chronometrie), aufbauend auf Bessels Astronomie und Helmholtz' Physiologie. Die schlichte Tippen-auf-Signal-Version ist eine allgemeine experimentelle Methode, kein Marken-Spiel.",methods:"Schalte Ablenkungen aus und halte deine Hand entspannt und in jedem Durchgang am selben Fleck ruhend. Halte nach dem Signal Ausschau, aber widersteh dem Drang, es vorwegzunehmen \u2014 den Zeitpunkt vorherzusagen f\xfchrt zu Fehlstarts, nicht zu schnelleren Werten. Mach kurze Bl\xf6cke mit vielen Durchg\xe4ngen statt weniger angespannter Versuche und verfolge deinen Durchschnitt und deine langsamsten Reaktionen, nicht nur deinen besten Zufallstreffer.",duration:"Die Reaktion ist erm\xfcdungsempfindlich, also halte sie kurz: 2 bis 5 Minuten konzentrierter Durchg\xe4nge, einmal am Tag, reichen v\xf6llig. Kurze, h\xe4ufige Sitzungen schlagen lange, und deine Werte sacken in dem Moment ab, in dem du m\xfcde, schl\xe4frig oder abgelenkt bist.",research:"Solide belegt ist nur das Enge: Mit \xdcbung wirst du in genau dieser Aufgabe messbar schneller und gleichm\xe4\xdfiger, vor allem indem du Fehlstarts und Aussetzer verringerst. Deine Untergrenze ist jedoch weitgehend durch die Neurophysiologie gesetzt \u2014 Nervenleitung und Verarbeitungsgeschwindigkeit \u2014, sodass ein gesunder Erwachsener nahe 200 bis 250 ms liegt und das nicht grenzenlos heruntertrainieren kann. Behauptungen, dass Reaktions\xfcbungen den Geist breit sch\xe4rfen, die Intelligenz heben oder den kognitiven Abbau verhindern, sind schwach und weitgehend unbewiesen; ein \xdcbertrag \xfcber die ge\xfcbte Aufgabe hinaus ist die Ausnahme, nicht die Regel. Dein Tageswert ist au\xdferdem ein empfindlicher Anzeiger von Schlaf, Wachheit und Erm\xfcdung.",rec:"Betrachte deinen Durchschnitt \xfcber viele Durchg\xe4nge als das eigentliche Ma\xdf und nimm einen schlechten Tag als Anlass, deinen Schlaf zu pr\xfcfen, statt h\xe4rter zu schuften.",faq:[["Kann ich meine Reaktionszeit wirklich schneller machen?","Ja, aber in Grenzen. \xdcbung verringert Fehlstarts und Aussetzer, sodass dein Durchschnitt besser wird, doch deine schnellstm\xf6gliche Antwort ist gr\xf6\xdftenteils durch die Verarbeitungsgeschwindigkeit von Nerven und Gehirn gedeckelt, die das Training nicht unbegrenzt senken kann."],["Was ist eine gute einfache Reaktionszeit?","Bei einem gesunden Erwachsenen liegt eine visuelle einfache Reaktion ungef\xe4hr bei 200 bis 250 ms. Behandle jeden einzelnen Wert vorsichtig \u2014 Erm\xfcdung, Schlaf, Koffein und das verwendete Ger\xe4t verschieben ihn alle."],["Macht mich das schlauer oder zu einem besseren Autofahrer?","Setze nicht auf einen breiten \xdcbertrag. Du wirst in dieser Aufgabe schneller, aber Belege, dass Reaktions\xfcbungen die allgemeine Intelligenz oder reale Fertigkeiten wie das Autofahren steigern, sind schwach, also bewerte es als Reaktions\xfcbung, nicht als Gehirn-Upgrade."]],variants:"Abwandlungen umfassen die Wahlreaktionszeit (w\xe4hle die richtige Antwort unter mehreren Zielen), Go/No-go-Aufgaben (handle bei manchen Reizen, halte bei anderen zur\xfcck), akustische statt visueller Signale und 'Triff-das-Ziel'-Versionen, in denen sich das Ziel auch bewegt und eine Zielkomponente hinzukommt."},pt:{about:"Targets: Reaction \xe9 uma tarefa simples de tempo de rea\xe7\xe3o. Voc\xea espera pelo sinal \u2014 um alvo aparece ou a tela muda de cor \u2014 e toca o mais r\xe1pido que conseguir, sem se adiantar antes da deixa. Todo o sentido \xe9 medir e raspar milissegundos do intervalo entre ver e agir.",benefit:"Treina a velocidade da sua rea\xe7\xe3o simples: o qu\xe3o r\xe1pido voc\xea detecta um est\xedmulo e dispara uma \xfanica resposta motora pr\xe9-planejada. Tamb\xe9m afia sua prontid\xe3o para agir e seu controle de impulsos, j\xe1 que reagir antes do sinal conta como erro.",history:"Medir a velocidade de resposta humana nasceu da astronomia do s\xe9culo XIX, em que Friedrich Bessel notou por volta de 1822 que diferentes observadores cronometravam de forma distinta a passagem das estrelas \u2014 a 'equa\xe7\xe3o pessoal'. Hermann von Helmholtz ent\xe3o mediu a velocidade do sinal nervoso em 1850, e o m\xe9todo amadureceu at\xe9 virar uma ferramenta da psicologia experimental. Da\xed o teste de rea\xe7\xe3o simples tornou-se um pilar de laborat\xf3rio e, muito mais tarde, item fixo do treino esportivo, impulsionando a pesquisa e os jogos.",creator:"N\xe3o h\xe1 um \xfanico inventor da tarefa de tempo de rea\xe7\xe3o. O fisiologista holand\xeas Franciscus Cornelis Donders \xe9 o pioneiro central: em 1868 ele formalizou o uso dos tempos de rea\xe7\xe3o para estudar processos mentais (cronometria mental), apoiando-se na astronomia de Bessel e na fisiologia de Helmholtz. A vers\xe3o simples de tocar ao sinal \xe9 um m\xe9todo experimental gen\xe9rico, n\xe3o um jogo de marca.",methods:"Elimine distra\xe7\xf5es e mantenha a m\xe3o relaxada e apoiada no mesmo lugar a cada tentativa. Fique atento ao sinal, mas resista ao impulso de antecip\xe1-lo \u2014 prever o momento leva a sa\xeddas em falso, n\xe3o a pontua\xe7\xf5es mais r\xe1pidas. Fa\xe7a blocos curtos com muitas tentativas em vez de algumas tentativas tensas, e acompanhe sua m\xe9dia e suas rea\xe7\xf5es mais lentas, n\xe3o apenas o seu melhor golpe de sorte.",duration:"A rea\xe7\xe3o \xe9 sens\xedvel ao cansa\xe7o, ent\xe3o mantenha-a breve: 2 a 5 minutos de tentativas focadas, uma vez por dia, bastam. Sess\xf5es curtas e frequentes batem as longas, e seus n\xfameros v\xe3o despencar no momento em que voc\xea estiver cansado, sonolento ou distra\xeddo.",research:"O que est\xe1 solidamente demonstrado \xe9 restrito: com a pr\xe1tica voc\xea fica mensuravelmente mais r\xe1pido e mais consistente nesta tarefa exata, sobretudo cortando sa\xeddas em falso e lapsos. Seu piso, por\xe9m, \xe9 em grande parte definido pela neurofisiologia \u2014 condu\xe7\xe3o nervosa e velocidade de processamento \u2014 ent\xe3o um adulto saud\xe1vel fica perto de 200-250 ms e n\xe3o consegue treinar isso para baixo sem limite. Afirma\xe7\xf5es de que exerc\xedcios de rea\xe7\xe3o afiam amplamente a mente, elevam a intelig\xeancia ou previnem o decl\xednio cognitivo s\xe3o fracas e em grande parte n\xe3o comprovadas; a transfer\xeancia al\xe9m da tarefa treinada \xe9 a exce\xe7\xe3o, n\xe3o a regra. Sua pontua\xe7\xe3o di\xe1ria tamb\xe9m \xe9 uma leitura sens\xedvel de sono, alerta e cansa\xe7o.",rec:"Trate sua m\xe9dia ao longo de muitas tentativas como a medida de verdade, e use um dia ruim como sinal para checar seu sono em vez de insistir mais forte.",faq:[["Eu consigo mesmo deixar meu tempo de rea\xe7\xe3o mais r\xe1pido?","Sim, mas dentro de limites. A pr\xe1tica apara sa\xeddas em falso e lapsos, ent\xe3o sua m\xe9dia melhora, mas sua resposta mais r\xe1pida poss\xedvel \xe9 em grande parte limitada pela velocidade de processamento do nervo e do c\xe9rebro, que o treino n\xe3o consegue baixar indefinidamente."],["O que \xe9 um bom tempo de rea\xe7\xe3o simples?","Para um adulto saud\xe1vel, uma rea\xe7\xe3o visual simples fica em torno de 200-250 ms. Trate qualquer n\xfamero isolado com cautela \u2014 cansa\xe7o, sono, cafe\xedna e o dispositivo que voc\xea usa, todos o deslocam."],["Isto vai me deixar mais inteligente ou um motorista melhor?","N\xe3o conte com uma transfer\xeancia ampla. Voc\xea ficar\xe1 mais r\xe1pido nesta tarefa, mas a evid\xeancia de que exerc\xedcios de rea\xe7\xe3o elevam a intelig\xeancia geral ou habilidades do mundo real como dirigir \xe9 fraca, ent\xe3o julgue isto como pr\xe1tica de rea\xe7\xe3o, n\xe3o como uma melhoria do c\xe9rebro."]],variants:"Varia\xe7\xf5es incluem o tempo de rea\xe7\xe3o de escolha (escolha a resposta certa entre v\xe1rios alvos), tarefas go/no-go (aja diante de algumas deixas, contenha-se diante de outras), sinais sonoros em vez de visuais e vers\xf5es de 'acerte o alvo' em que o alvo tamb\xe9m se move, acrescentando um componente de mira."},hi:{about:"Targets: Reaction \u090f\u0915 \u0938\u0930\u0932 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0938\u092e\u092f (\u0930\u093f\u090f\u0915\u094d\u0936\u0928-\u091f\u093e\u0907\u092e) \u0935\u093e\u0932\u093e \u0915\u093e\u0930\u094d\u092f \u0939\u0948\u0964 \u0906\u092a \u0938\u0902\u0915\u0947\u0924 \u0915\u093e \u0907\u0902\u0924\u091c\u093c\u093e\u0930 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902 \u2014 \u090f\u0915 \u0932\u0915\u094d\u0937\u094d\u092f \u092a\u094d\u0930\u0915\u091f \u0939\u094b\u0924\u093e \u0939\u0948 \u092f\u093e \u0938\u094d\u0915\u094d\u0930\u0940\u0928 \u0915\u093e \u0930\u0902\u0917 \u092c\u0926\u0932\u0924\u093e \u0939\u0948 \u2014 \u0914\u0930 \u091c\u093f\u0924\u0928\u0940 \u0924\u0947\u091c\u093c\u0940 \u0938\u0947 \u092e\u0941\u092e\u0915\u093f\u0928 \u0939\u094b \u091f\u0948\u092a \u0915\u0930\u0924\u0947 \u0939\u0948\u0902, \u092c\u093f\u0928\u093e \u0938\u0902\u0915\u0947\u0924 \u0938\u0947 \u092a\u0939\u0932\u0947 \u0939\u0921\u093c\u092c\u0921\u093c\u093e\u090f\u0964 \u092a\u0942\u0930\u093e \u092e\u0915\u093c\u0938\u0926 \u0939\u0948 \u0926\u0947\u0916\u0928\u0947 \u0914\u0930 \u0915\u0926\u092e \u0909\u0920\u093e\u0928\u0947 \u0915\u0947 \u092c\u0940\u091a \u0915\u0947 \u0905\u0902\u0924\u0930\u093e\u0932 \u0915\u094b \u0928\u093e\u092a\u0928\u093e \u0914\u0930 \u0909\u0938\u092e\u0947\u0902 \u0938\u0947 \u092e\u093f\u0932\u0940\u0938\u0947\u0915\u0902\u0921 \u091b\u093e\u0901\u091f\u0928\u093e\u0964",benefit:"\u092f\u0939 \u0906\u092a\u0915\u0940 \u0938\u0930\u0932 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0915\u0940 \u0917\u0924\u093f \u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0930\u093e\u0924\u093e \u0939\u0948: \u0915\u093f\u0924\u0928\u0940 \u091c\u0932\u094d\u0926\u0940 \u0906\u092a \u0915\u093f\u0938\u0940 \u0909\u0926\u094d\u0926\u0940\u092a\u0928 (\u0938\u094d\u091f\u093f\u092e\u0941\u0932\u0938) \u0915\u094b \u092d\u093e\u0901\u092a\u0924\u0947 \u0939\u0948\u0902 \u0914\u0930 \u090f\u0915 \u0905\u0915\u0947\u0932\u0940, \u092a\u0939\u0932\u0947 \u0938\u0947 \u0924\u092f \u0936\u093e\u0930\u0940\u0930\u093f\u0915 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0926\u093e\u0917\u0924\u0947 \u0939\u0948\u0902\u0964 \u092f\u0939 \u0915\u0926\u092e \u0909\u0920\u093e\u0928\u0947 \u0915\u0940 \u0906\u092a\u0915\u0940 \u0924\u0924\u094d\u092a\u0930\u0924\u093e \u0914\u0930 \u0906\u0935\u0947\u0917-\u0928\u093f\u092f\u0902\u0924\u094d\u0930\u0923 \u0915\u094b \u092d\u0940 \u0927\u093e\u0930 \u0926\u0947\u0924\u093e \u0939\u0948, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u0938\u0902\u0915\u0947\u0924 \u0938\u0947 \u092a\u0939\u0932\u0947 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0915\u0930\u0928\u093e \u091a\u0942\u0915 \u092e\u093e\u0928\u0940 \u091c\u093e\u0924\u0940 \u0939\u0948\u0964",history:"\u0907\u0902\u0938\u093e\u0928\u0940 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0917\u0924\u093f \u0915\u094b \u0928\u093e\u092a\u0928\u093e \u0909\u0928\u094d\u0928\u0940\u0938\u0935\u0940\u0902 \u0938\u0926\u0940 \u0915\u0947 \u0916\u0917\u094b\u0932\u0936\u093e\u0938\u094d\u0924\u094d\u0930 \u0938\u0947 \u092a\u0928\u092a\u093e, \u091c\u0939\u093e\u0901 Friedrich Bessel \u0928\u0947 \u0932\u0917\u092d\u0917 1822 \u092e\u0947\u0902 \u0926\u0947\u0916\u093e \u0915\u093f \u0905\u0932\u0917-\u0905\u0932\u0917 \u092a\u094d\u0930\u0947\u0915\u094d\u0937\u0915 \u0924\u093e\u0930\u094b\u0902 \u0915\u0947 \u092a\u093e\u0930\u0917\u092e\u0928 \u0915\u093e \u0938\u092e\u092f \u0905\u0932\u0917-\u0905\u0932\u0917 \u0906\u0901\u0915\u0924\u0947 \u0939\u0948\u0902 \u2014 \u092f\u093e\u0928\u0940 '\u0935\u094d\u092f\u0915\u094d\u0924\u093f\u0917\u0924 \u0938\u092e\u0940\u0915\u0930\u0923' (\u092a\u0930\u094d\u0938\u0928\u0932 \u0907\u0915\u094d\u0935\u0947\u0936\u0928)\u0964 \u092b\u093f\u0930 Hermann von Helmholtz \u0928\u0947 1850 \u092e\u0947\u0902 \u0924\u0902\u0924\u094d\u0930\u093f\u0915\u093e-\u0938\u0902\u0915\u0947\u0924 \u0915\u0940 \u0917\u0924\u093f \u0928\u093e\u092a\u0940, \u0914\u0930 \u092f\u0939 \u0935\u093f\u0927\u093f \u092a\u094d\u0930\u093e\u092f\u094b\u0917\u093f\u0915 \u092e\u0928\u094b\u0935\u093f\u091c\u094d\u091e\u093e\u0928 \u0915\u0947 \u090f\u0915 \u0914\u091c\u093c\u093e\u0930 \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u092a\u0930\u093f\u092a\u0915\u094d\u0935 \u0939\u0941\u0908\u0964 \u0935\u0939\u093e\u0901 \u0938\u0947 \u0938\u0930\u0932-\u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u092a\u0930\u0940\u0915\u094d\u0937\u0923 \u092a\u094d\u0930\u092f\u094b\u0917\u0936\u093e\u0932\u093e \u0915\u093e \u090f\u0915 \u092a\u094d\u0930\u092e\u0941\u0916 \u0939\u093f\u0938\u094d\u0938\u093e \u092c\u0928\u093e \u0914\u0930, \u092c\u0939\u0941\u0924 \u092c\u093e\u0926 \u092e\u0947\u0902, \u0916\u0947\u0932-\u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u0915\u093e \u090f\u0915 \u0938\u094d\u0925\u093e\u092f\u0940 \u0905\u0902\u0917, \u091c\u094b \u0936\u094b\u0927 \u0924\u0925\u093e \u0917\u0947\u092e\u093f\u0902\u0917 \u0915\u094b \u0906\u0917\u0947 \u092c\u0922\u093c\u093e\u0924\u093e \u0939\u0948\u0964",creator:"\u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0938\u092e\u092f \u0915\u093e\u0930\u094d\u092f \u0915\u093e \u0915\u094b\u0908 \u090f\u0915\u092e\u093e\u0924\u094d\u0930 \u0906\u0935\u093f\u0937\u094d\u0915\u093e\u0930\u0915 \u0928\u0939\u0940\u0902 \u0939\u0948\u0964 \u0921\u091a \u0936\u0930\u0940\u0930-\u0915\u094d\u0930\u093f\u092f\u093e-\u0935\u093f\u091c\u094d\u091e\u093e\u0928\u0940 (\u092b\u093c\u093f\u091c\u093c\u093f\u092f\u094b\u0932\u0949\u091c\u093f\u0938\u094d\u091f) Franciscus Cornelis Donders \u092e\u0941\u0916\u094d\u092f \u0905\u0917\u094d\u0930\u0926\u0942\u0924 \u0939\u0948\u0902: 1868 \u092e\u0947\u0902 \u0909\u0928\u094d\u0939\u094b\u0902\u0928\u0947 \u092e\u093e\u0928\u0938\u093f\u0915 \u092a\u094d\u0930\u0915\u094d\u0930\u093f\u092f\u093e\u0913\u0902 \u0915\u0947 \u0905\u0927\u094d\u092f\u092f\u0928 \u0915\u0947 \u0932\u093f\u090f \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0938\u092e\u092f \u0915\u0947 \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0915\u094b \u0914\u092a\u091a\u093e\u0930\u093f\u0915 \u0930\u0942\u092a \u0926\u093f\u092f\u093e (\u092e\u093e\u0928\u0938\u093f\u0915 \u0915\u093e\u0932\u092e\u093e\u092a\u0928, \u092f\u093e\u0928\u0940 \u092e\u0947\u0902\u091f\u0932 \u0915\u094d\u0930\u094b\u0928\u094b\u092e\u0947\u091f\u094d\u0930\u0940), \u091c\u094b Bessel \u0915\u0947 \u0916\u0917\u094b\u0932\u0936\u093e\u0938\u094d\u0924\u094d\u0930 \u0914\u0930 Helmholtz \u0915\u0947 \u0936\u0930\u0940\u0930-\u0915\u094d\u0930\u093f\u092f\u093e-\u0935\u093f\u091c\u094d\u091e\u093e\u0928 \u092a\u0930 \u0906\u0927\u093e\u0930\u093f\u0924 \u0925\u093e\u0964 \u0938\u0902\u0915\u0947\u0924-\u092a\u0930-\u091f\u0948\u092a \u0935\u093e\u0932\u093e \u0938\u093e\u0926\u093e \u0930\u0942\u092a \u090f\u0915 \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u092a\u094d\u0930\u093e\u092f\u094b\u0917\u093f\u0915 \u0935\u093f\u0927\u093f \u0939\u0948, \u0915\u094b\u0908 \u092c\u094d\u0930\u093e\u0902\u0921\u0947\u0921 \u0917\u0947\u092e \u0928\u0939\u0940\u0902\u0964",methods:"\u0927\u094d\u092f\u093e\u0928 \u092d\u091f\u0915\u093e\u0928\u0947 \u0935\u093e\u0932\u0940 \u091a\u0940\u091c\u093c\u0947\u0902 \u0939\u091f\u093e \u0926\u0940\u091c\u093f\u090f \u0914\u0930 \u0939\u0930 \u092c\u093e\u0930\u0940 \u092a\u0930 \u0905\u092a\u0928\u093e \u0939\u093e\u0925 \u0922\u0940\u0932\u093e \u0924\u0925\u093e \u0909\u0938\u0940 \u090f\u0915 \u091c\u0917\u0939 \u091f\u093f\u0915\u093e \u0939\u0941\u0906 \u0930\u0916\u093f\u090f\u0964 \u0938\u0902\u0915\u0947\u0924 \u0915\u0947 \u0932\u093f\u090f \u0924\u093e\u0915 \u092e\u0947\u0902 \u0930\u0939\u093f\u090f \u092e\u0917\u0930 \u0909\u0938\u0915\u093e \u092a\u0942\u0930\u094d\u0935\u093e\u0928\u0941\u092e\u093e\u0928 \u0932\u0917\u093e\u0928\u0947 \u0915\u0940 \u0907\u091a\u094d\u091b\u093e \u0915\u094b \u0930\u094b\u0915\u093f\u090f \u2014 \u0938\u092e\u092f \u0915\u093e \u0905\u0902\u0926\u093e\u091c\u093c\u093e \u0932\u0917\u093e\u0928\u093e \u091d\u0942\u0920\u0940 \u0936\u0941\u0930\u0941\u0906\u0924 (\u092b\u093c\u0949\u0932\u094d\u0938 \u0938\u094d\u091f\u093e\u0930\u094d\u091f) \u0915\u0940 \u0913\u0930 \u0932\u0947 \u091c\u093e\u0924\u093e \u0939\u0948, \u0924\u0947\u091c\u093c \u0938\u094d\u0915\u094b\u0930 \u0915\u0940 \u0913\u0930 \u0928\u0939\u0940\u0902\u0964 \u0915\u0941\u091b \u0924\u0928\u093e\u0935\u0917\u094d\u0930\u0938\u094d\u0924 \u0915\u094b\u0936\u093f\u0936\u094b\u0902 \u0915\u0947 \u092c\u091c\u093e\u092f \u0915\u0908 \u092c\u093e\u0930\u093f\u092f\u094b\u0902 \u0915\u0947 \u091b\u094b\u091f\u0947 \u0916\u0902\u0921 \u091a\u0932\u093e\u0907\u090f, \u0914\u0930 \u0938\u093f\u0930\u094d\u092b\u093c \u0905\u092a\u0928\u0947 \u0938\u092c\u0938\u0947 \u0905\u091a\u094d\u091b\u0947 \u0938\u0902\u092f\u094b\u0917\u0935\u0936 \u0928\u0924\u0940\u091c\u0947 \u0915\u094b \u0928\u0939\u0940\u0902, \u092c\u0932\u094d\u0915\u093f \u0905\u092a\u0928\u0947 \u0914\u0938\u0924 \u0914\u0930 \u0938\u092c\u0938\u0947 \u0927\u0940\u092e\u0940 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e\u0913\u0902 \u0915\u094b \u092d\u0940 \u0926\u0947\u0916\u093f\u090f\u0964",duration:"\u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0925\u0915\u093e\u0928 \u0915\u0947 \u092a\u094d\u0930\u0924\u093f \u0938\u0902\u0935\u0947\u0926\u0928\u0936\u0940\u0932 \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0907\u0938\u0947 \u091b\u094b\u091f\u093e \u0930\u0916\u093f\u090f: \u0930\u094b\u091c\u093c \u090f\u0915 \u092c\u093e\u0930 2-5 \u092e\u093f\u0928\u091f \u0915\u0940 \u0915\u0947\u0902\u0926\u094d\u0930\u093f\u0924 \u092c\u093e\u0930\u093f\u092f\u093e\u0901 \u0915\u093e\u092b\u093c\u0940 \u0939\u0948\u0902\u0964 \u091b\u094b\u091f\u0947, \u092c\u093e\u0930-\u092c\u093e\u0930 \u0915\u0947 \u0938\u0924\u094d\u0930 \u0932\u0902\u092c\u0947 \u0938\u0924\u094d\u0930\u094b\u0902 \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u0939\u0948\u0902, \u0914\u0930 \u091c\u0948\u0938\u0947 \u0939\u0940 \u0906\u092a \u0925\u0915\u0947, \u0928\u0940\u0902\u0926 \u092e\u0947\u0902, \u092f\u093e \u092d\u091f\u0915\u0947 \u0939\u0941\u090f \u0939\u094b\u0902\u0917\u0947 \u0906\u092a\u0915\u0947 \u0906\u0901\u0915\u0921\u093c\u0947 \u0917\u093f\u0930 \u091c\u093e\u090f\u0901\u0917\u0947\u0964",research:"\u091c\u094b \u0920\u094b\u0938 \u0922\u0902\u0917 \u0938\u0947 \u0926\u093f\u0916\u093e\u092f\u093e \u0917\u092f\u093e \u0939\u0948 \u0935\u0939 \u0938\u0940\u092e\u093f\u0924 \u0939\u0948: \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0947 \u0938\u093e\u0925 \u0906\u092a \u0907\u0938\u0940 \u0916\u093e\u0938 \u0915\u093e\u0930\u094d\u092f \u092e\u0947\u0902 \u0928\u093e\u092a-\u0924\u094c\u0932\u0915\u0930 \u0924\u0947\u091c\u093c \u0914\u0930 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0938\u0902\u0917\u0924 (\u0915\u0902\u0938\u093f\u0938\u094d\u091f\u0947\u0902\u091f) \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902, \u092e\u0941\u0916\u094d\u092f\u0924\u0903 \u091d\u0942\u0920\u0940 \u0936\u0941\u0930\u0941\u0906\u0924\u094b\u0902 \u0914\u0930 \u091a\u0942\u0915\u094b\u0902 \u0915\u094b \u0918\u091f\u093e\u0915\u0930\u0964 \u092a\u0930 \u0906\u092a\u0915\u0940 \u0928\u093f\u091a\u0932\u0940 \u0938\u0940\u092e\u093e \u0915\u093e\u092b\u093c\u0940 \u0939\u0926 \u0924\u0915 \u0924\u0902\u0924\u094d\u0930\u093f\u0915\u093e-\u0936\u0930\u0940\u0930-\u0915\u094d\u0930\u093f\u092f\u093e-\u0935\u093f\u091c\u094d\u091e\u093e\u0928 \u0938\u0947 \u0924\u092f \u0939\u094b\u0924\u0940 \u0939\u0948 \u2014 \u0924\u0902\u0924\u094d\u0930\u093f\u0915\u093e-\u091a\u093e\u0932\u0928 \u0914\u0930 \u092a\u094d\u0930\u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0917\u0924\u093f \u2014 \u0907\u0938\u0932\u093f\u090f \u090f\u0915 \u0938\u094d\u0935\u0938\u094d\u0925 \u0935\u092f\u0938\u094d\u0915 \u0915\u0930\u0940\u092c 200-250 \u092e\u093f.\u0938\u0947. \u0915\u0947 \u092a\u093e\u0938 \u092c\u0948\u0920\u0924\u093e \u0939\u0948 \u0914\u0930 \u0907\u0938\u0947 \u092c\u093f\u0928\u093e \u0915\u093f\u0938\u0940 \u0939\u0926 \u0915\u0947 \u0918\u091f\u093e \u0928\u0939\u0940\u0902 \u0938\u0915\u0924\u093e\u0964 \u092f\u0939 \u0926\u093e\u0935\u093e \u0915\u093f \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0915\u0938\u0930\u0924\u0947\u0902 \u0926\u093f\u092e\u093e\u0917 \u0915\u094b \u0935\u094d\u092f\u093e\u092a\u0915 \u0930\u0942\u092a \u0938\u0947 \u0927\u093e\u0930 \u0926\u0947\u0924\u0940 \u0939\u0948\u0902, \u092c\u0941\u0926\u094d\u0927\u093f \u092c\u0922\u093c\u093e\u0924\u0940 \u0939\u0948\u0902, \u092f\u093e \u0938\u0902\u091c\u094d\u091e\u093e\u0928\u093e\u0924\u094d\u092e\u0915 \u0917\u093f\u0930\u093e\u0935\u091f \u0930\u094b\u0915\u0924\u0940 \u0939\u0948\u0902 \u2014 \u0915\u092e\u091c\u093c\u094b\u0930 \u0914\u0930 \u0915\u093e\u092b\u093c\u0940 \u0939\u0926 \u0924\u0915 \u0905\u0938\u093e\u092c\u093f\u0924 \u0939\u0948; \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u093f\u0924 \u0915\u093e\u0930\u094d\u092f \u0938\u0947 \u092a\u0930\u0947 \u0939\u0938\u094d\u0924\u093e\u0902\u0924\u0930\u0923 \u0928\u093f\u092f\u092e \u0928\u0939\u0940\u0902, \u0905\u092a\u0935\u093e\u0926 \u0939\u0948\u0964 \u0906\u092a\u0915\u093e \u0930\u094b\u091c\u093c \u0915\u093e \u0938\u094d\u0915\u094b\u0930 \u0928\u0940\u0902\u0926, \u0938\u0924\u0930\u094d\u0915\u0924\u093e \u0914\u0930 \u0925\u0915\u093e\u0928 \u0915\u093e \u090f\u0915 \u0938\u0902\u0935\u0947\u0926\u0928\u0936\u0940\u0932 \u092a\u093e\u0920 \u092d\u0940 \u0939\u0948\u0964",rec:"\u0915\u0908 \u092c\u093e\u0930\u093f\u092f\u094b\u0902 \u092a\u0930 \u0905\u092a\u0928\u0947 \u0914\u0938\u0924 \u0915\u094b \u0939\u0940 \u0905\u0938\u0932\u0940 \u092e\u093e\u092a \u092e\u093e\u0928\u093f\u090f, \u0914\u0930 \u0915\u093f\u0938\u0940 \u092c\u0941\u0930\u0947 \u0926\u093f\u0928 \u0915\u094b \u0914\u0930 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u092a\u093f\u0938\u093e\u0908 \u0915\u093e \u0928\u0939\u0940\u0902, \u092c\u0932\u094d\u0915\u093f \u0905\u092a\u0928\u0940 \u0928\u0940\u0902\u0926 \u091c\u093e\u0901\u091a\u0928\u0947 \u0915\u093e \u0938\u0902\u0915\u0947\u0924 \u092e\u093e\u0928\u093f\u090f\u0964",faq:[["\u0915\u094d\u092f\u093e \u092e\u0948\u0902 \u0938\u091a\u092e\u0941\u091a \u0905\u092a\u0928\u093e \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0938\u092e\u092f \u0924\u0947\u091c\u093c \u0915\u0930 \u0938\u0915\u0924\u093e \u0939\u0942\u0901?","\u0939\u093e\u0901, \u092e\u0917\u0930 \u0939\u0926\u094b\u0902 \u0915\u0947 \u092d\u0940\u0924\u0930\u0964 \u0905\u092d\u094d\u092f\u093e\u0938 \u091d\u0942\u0920\u0940 \u0936\u0941\u0930\u0941\u0906\u0924\u094b\u0902 \u0914\u0930 \u091a\u0942\u0915\u094b\u0902 \u0915\u094b \u0915\u093e\u091f\u0924\u093e \u0939\u0948 \u091c\u093f\u0938\u0938\u0947 \u0906\u092a\u0915\u093e \u0914\u0938\u0924 \u0938\u0941\u0927\u0930\u0924\u093e \u0939\u0948, \u092b\u093f\u0930 \u092d\u0940 \u0906\u092a\u0915\u0940 \u0938\u092c\u0938\u0947 \u0924\u0947\u091c\u093c \u092e\u0941\u092e\u0915\u093f\u0928 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u091c\u093c\u094d\u092f\u093e\u0926\u093e\u0924\u0930 \u0924\u0902\u0924\u094d\u0930\u093f\u0915\u093e \u0914\u0930 \u0926\u093f\u092e\u093e\u0917\u0940 \u092a\u094d\u0930\u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0917\u0924\u093f \u0938\u0947 \u092c\u0901\u0927\u0940 \u0939\u094b\u0924\u0940 \u0939\u0948, \u091c\u093f\u0938\u0947 \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u0905\u0928\u0902\u0924 \u0939\u0926 \u0924\u0915 \u0918\u091f\u093e \u0928\u0939\u0940\u0902 \u0938\u0915\u0924\u093e\u0964"],["\u090f\u0915 \u0905\u091a\u094d\u091b\u093e \u0938\u0930\u0932 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0938\u092e\u092f \u0915\u094d\u092f\u093e \u0939\u094b\u0924\u093e \u0939\u0948?","\u090f\u0915 \u0938\u094d\u0935\u0938\u094d\u0925 \u0935\u092f\u0938\u094d\u0915 \u0915\u0947 \u0932\u093f\u090f \u0926\u0943\u0936\u094d\u092f \u0938\u0930\u0932 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u092e\u094b\u091f\u0947 \u0924\u094c\u0930 \u092a\u0930 200-250 \u092e\u093f.\u0938\u0947. \u0915\u0947 \u0906\u0938\u092a\u093e\u0938 \u092c\u0948\u0920\u0924\u0940 \u0939\u0948\u0964 \u0915\u093f\u0938\u0940 \u092d\u0940 \u0905\u0915\u0947\u0932\u0947 \u0906\u0901\u0915\u0921\u093c\u0947 \u0915\u094b \u0938\u093e\u0935\u0927\u093e\u0928\u0940 \u0938\u0947 \u0932\u0940\u091c\u093f\u090f \u2014 \u0925\u0915\u093e\u0928, \u0928\u0940\u0902\u0926, \u0915\u0948\u092b\u093c\u0940\u0928 \u0914\u0930 \u0906\u092a\u0915\u0947 \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0915\u093f\u090f \u091c\u093e \u0930\u0939\u0947 \u0921\u093f\u0935\u093e\u0907\u0938, \u0938\u092d\u0940 \u0907\u0938\u0947 \u0916\u093f\u0938\u0915\u093e \u0926\u0947\u0924\u0947 \u0939\u0948\u0902\u0964"],["\u0915\u094d\u092f\u093e \u092f\u0939 \u092e\u0941\u091d\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0939\u094b\u0936\u093f\u092f\u093e\u0930 \u092f\u093e \u092c\u0947\u0939\u0924\u0930 \u0921\u094d\u0930\u093e\u0907\u0935\u0930 \u092c\u0928\u093e \u0926\u0947\u0917\u093e?","\u0935\u094d\u092f\u093e\u092a\u0915 \u0938\u094d\u0925\u093e\u0928\u093e\u0902\u0924\u0930\u0923 \u092a\u0930 \u092e\u0924 \u091f\u0947\u0915\u093f\u090f\u0964 \u0906\u092a \u0907\u0938 \u0915\u093e\u0930\u094d\u092f \u092e\u0947\u0902 \u0924\u0947\u091c\u093c \u0939\u094b \u091c\u093e\u090f\u0901\u0917\u0947, \u092e\u0917\u0930 \u0907\u0938\u0915\u093e \u0938\u092c\u0942\u0924 \u0915\u092e\u091c\u093c\u094b\u0930 \u0939\u0948 \u0915\u093f \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0915\u0938\u0930\u0924\u0947\u0902 \u0906\u092e \u092c\u0941\u0926\u094d\u0927\u093f \u092f\u093e \u0921\u094d\u0930\u093e\u0907\u0935\u093f\u0902\u0917 \u091c\u0948\u0938\u0947 \u0905\u0938\u0932-\u0926\u0941\u0928\u093f\u092f\u093e \u0915\u0947 \u0915\u094c\u0936\u0932 \u092c\u0922\u093c\u093e\u0924\u0940 \u0939\u0948\u0902, \u0907\u0938\u0932\u093f\u090f \u0907\u0938\u0947 \u0926\u093f\u092e\u093e\u0917\u0940 \u0905\u092a\u0917\u094d\u0930\u0947\u0921 \u0928\u0939\u0940\u0902, \u092c\u0932\u094d\u0915\u093f \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u092e\u093e\u0928\u0915\u0930 \u0906\u0901\u0915\u093f\u090f\u0964"]],variants:"\u092c\u0926\u0932\u093e\u0935\u094b\u0902 \u092e\u0947\u0902 \u0936\u093e\u092e\u093f\u0932 \u0939\u0948\u0902 \u091a\u092f\u0928-\u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0938\u092e\u092f (\u0915\u0908 \u0932\u0915\u094d\u0937\u094d\u092f\u094b\u0902 \u092e\u0947\u0902 \u0938\u0947 \u0938\u0939\u0940 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e \u091a\u0941\u0928\u093f\u090f), \u0917\u094b/\u0928\u094b-\u0917\u094b \u0915\u093e\u0930\u094d\u092f (\u0915\u0941\u091b \u0938\u0902\u0915\u0947\u0924\u094b\u0902 \u092a\u0930 \u0915\u0926\u092e \u0909\u0920\u093e\u0907\u090f, \u0915\u0941\u091b \u092a\u0930 \u0930\u094b\u0915 \u0930\u0916\u093f\u090f), \u0926\u0943\u0936\u094d\u092f \u0915\u0947 \u092c\u091c\u093e\u092f \u0936\u094d\u0930\u0935\u094d\u092f \u0938\u0902\u0915\u0947\u0924, \u0914\u0930 '\u0932\u0915\u094d\u0937\u094d\u092f-\u092a\u0930-\u0939\u0925\u094c\u0921\u093c\u093e' \u0935\u093e\u0932\u0947 \u0930\u0942\u092a \u091c\u0939\u093e\u0901 \u0932\u0915\u094d\u0937\u094d\u092f \u091a\u0932\u0924\u093e \u092d\u0940 \u0939\u0948, \u091c\u094b \u090f\u0915 \u0928\u093f\u0936\u093e\u0928\u093e \u0932\u0917\u093e\u0928\u0947 \u0935\u093e\u0932\u093e \u0905\u0902\u0936 \u091c\u094b\u0921\u093c \u0926\u0947\u0924\u093e \u0939\u0948\u0964"},zh:{about:"\u300a\u76ee\u6807\uff1a\u53cd\u5e94\u300b\u662f\u4e00\u4e2a\u7b80\u5355\u7684\u53cd\u5e94\u65f6\u4efb\u52a1\u3002\u4f60\u7b49\u5f85\u4fe1\u53f7\u2014\u2014\u4e00\u4e2a\u76ee\u6807\u51fa\u73b0\uff0c\u6216\u5c4f\u5e55\u53d8\u8272\u2014\u2014\u7136\u540e\u4ee5\u4f60\u6700\u5feb\u7684\u901f\u5ea6\u70b9\u51fb\uff0c\u4e14\u4e0d\u80fd\u5728\u63d0\u793a\u51fa\u73b0\u4e4b\u524d\u62a2\u8dd1\u3002\u5b83\u7684\u5168\u90e8\u610f\u4e49\u5c31\u5728\u4e8e\u6d4b\u91cf\u5e76\u524a\u51cf\u4f60\u4ece\u770b\u5230\u5230\u884c\u52a8\u4e4b\u95f4\u90a3\u6bb5\u95f4\u9694\u7684\u6beb\u79d2\u6570\u3002",benefit:"\u5b83\u8bad\u7ec3\u4f60\u7b80\u5355\u53cd\u5e94\u7684\u901f\u5ea6\uff1a\u4f60\u591a\u5feb\u80fd\u4fa6\u6d4b\u5230\u4e00\u4e2a\u523a\u6fc0\uff0c\u5e76\u53d1\u51fa\u4e00\u4e2a\u4e8b\u5148\u51c6\u5907\u597d\u7684\u5355\u4e00\u8fd0\u52a8\u53cd\u5e94\u3002\u5b83\u4e5f\u78e8\u7ec3\u4f60\u884c\u52a8\u7684\u5c31\u7eea\u72b6\u6001\u548c\u51b2\u52a8\u63a7\u5236\u529b\uff0c\u56e0\u4e3a\u5728\u4fe1\u53f7\u51fa\u73b0\u4e4b\u524d\u5c31\u53cd\u5e94\u4f1a\u88ab\u7b97\u4f5c\u5931\u8bef\u3002",history:"\u6d4b\u91cf\u4eba\u7684\u53cd\u5e94\u901f\u5ea6\u6e90\u4e8e19\u4e16\u7eaa\u7684\u5929\u6587\u5b66\u3002\u7ea61822\u5e74\uff0cFriedrich Bessel\u6ce8\u610f\u5230\u4e0d\u540c\u89c2\u6d4b\u8005\u5bf9\u6052\u661f\u51cc\u65e5\u7684\u8ba1\u65f6\u5404\u4e0d\u76f8\u540c\u2014\u2014\u8fd9\u5c31\u662f\u300e\u4eba\u5dee\u65b9\u7a0b\u300f\u3002Hermann von Helmholtz\u968f\u540e\u57281850\u5e74\u6d4b\u91cf\u4e86\u795e\u7ecf\u4fe1\u53f7\u7684\u4f20\u5bfc\u901f\u5ea6\uff0c\u8fd9\u5957\u65b9\u6cd5\u9010\u6e10\u6210\u719f\u4e3a\u5b9e\u9a8c\u5fc3\u7406\u5b66\u7684\u5de5\u5177\u3002\u7531\u6b64\uff0c\u7b80\u5355\u53cd\u5e94\u6d4b\u8bd5\u6210\u4e3a\u5b9e\u9a8c\u5ba4\u7684\u5e38\u5907\u9879\u76ee\uff0c\u5e76\u5728\u5f88\u4e45\u4e4b\u540e\u6210\u4e3a\u4f53\u80b2\u8bad\u7ec3\u3001\u79d1\u7814\u9a71\u52a8\u548c\u6e38\u620f\u4e2d\u7684\u56fa\u5b9a\u73af\u8282\u3002",creator:"\u53cd\u5e94\u65f6\u4efb\u52a1\u6ca1\u6709\u5355\u4e00\u7684\u53d1\u660e\u8005\u3002\u8377\u5170\u751f\u7406\u5b66\u5bb6Franciscus Cornelis Donders\u662f\u5173\u952e\u7684\u5148\u9a71\uff1a1868\u5e74\uff0c\u4ed6\u5728Bessel\u7684\u5929\u6587\u5b66\u548cHelmholtz\u7684\u751f\u7406\u5b66\u57fa\u7840\u4e0a\uff0c\u6b63\u5f0f\u786e\u7acb\u4e86\u7528\u53cd\u5e94\u65f6\u6765\u7814\u7a76\u5fc3\u7406\u8fc7\u7a0b\uff08\u5fc3\u7406\u8ba1\u65f6\u5b66\uff09\u7684\u505a\u6cd5\u3002\u800c\u90a3\u79cd\u6734\u7d20\u7684\u300e\u89c1\u4fe1\u53f7\u5373\u70b9\u51fb\u300f\u7248\u672c\uff0c\u662f\u4e00\u79cd\u901a\u7528\u7684\u5b9e\u9a8c\u65b9\u6cd5\uff0c\u5e76\u975e\u67d0\u4e2a\u54c1\u724c\u7684\u6e38\u620f\u3002",methods:"\u6392\u9664\u5e72\u6270\uff0c\u8ba9\u4f60\u7684\u624b\u4fdd\u6301\u653e\u677e\uff0c\u6bcf\u4e00\u8f6e\u90fd\u6401\u5728\u540c\u4e00\u4e2a\u4f4d\u7f6e\u3002\u7559\u610f\u4fe1\u53f7\uff0c\u4f46\u8981\u62b5\u4f4f\u63d0\u524d\u9884\u5224\u5b83\u7684\u51b2\u52a8\u2014\u2014\u9884\u6d4b\u65f6\u673a\u5e26\u6765\u7684\u662f\u62a2\u8dd1\uff0c\u800c\u4e0d\u662f\u66f4\u5feb\u7684\u6210\u7ee9\u3002\u591a\u505a\u51e0\u4e2a\u7531\u8bb8\u591a\u6b21\u8bd5\u9a8c\u7ec4\u6210\u7684\u77ed\u56de\u5408\uff0c\u800c\u4e0d\u662f\u51e0\u6b21\u7d27\u5f20\u516e\u516e\u7684\u5c1d\u8bd5\uff0c\u5e76\u8ffd\u8e2a\u4f60\u7684\u5e73\u5747\u503c\u548c\u4f60\u6700\u6162\u7684\u51e0\u6b21\u53cd\u5e94\uff0c\u800c\u4e0d\u53ea\u662f\u4f60\u4fa5\u5e78\u7684\u6700\u4f73\u6210\u7ee9\u3002",duration:"\u53cd\u5e94\u5bf9\u75b2\u52b3\u5f88\u654f\u611f\uff0c\u6240\u4ee5\u8981\u4fdd\u6301\u7b80\u77ed\uff1a\u6bcf\u5929\u4e00\u6b21\u3001\u4e13\u6ce8\u5730\u7ec32\u52305\u5206\u949f\u5c31\u8db3\u591f\u3002\u77ed\u800c\u9891\u7e41\u7684\u7ec3\u4e60\u80dc\u8fc7\u5197\u957f\u7684\u7ec3\u4e60\uff0c\u800c\u4e14\u53ea\u8981\u4f60\u4e00\u7d2f\u3001\u4e00\u56f0\u6216\u4e00\u5206\u795e\uff0c\u4f60\u7684\u6570\u5b57\u7acb\u523b\u5c31\u4f1a\u4e0b\u6ed1\u3002",research:"\u5f97\u5230\u624e\u5b9e\u8bc1\u660e\u7684\u7ed3\u8bba\u5f88\u7a84\uff1a\u968f\u7740\u7ec3\u4e60\uff0c\u4f60\u5728\u8fd9\u4e2a\u7279\u5b9a\u4efb\u52a1\u4e0a\u4f1a\u53d8\u5f97\u660e\u663e\u66f4\u5feb\u3001\u66f4\u7a33\u5b9a\uff0c\u4e3b\u8981\u662f\u9760\u51cf\u5c11\u62a2\u8dd1\u548c\u8d70\u795e\u3002\u7136\u800c\u4f60\u7684\u4e0b\u9650\u5728\u5f88\u5927\u7a0b\u5ea6\u4e0a\u7531\u795e\u7ecf\u751f\u7406\u5b66\u51b3\u5b9a\u2014\u2014\u795e\u7ecf\u4f20\u5bfc\u548c\u52a0\u5de5\u901f\u5ea6\u2014\u2014\u6240\u4ee5\u4e00\u4e2a\u5065\u5eb7\u7684\u6210\u5e74\u4eba\u7a33\u5b9a\u5728\u7ea6200\u5230250\u6beb\u79d2\uff0c\u65e0\u6cd5\u628a\u5b83\u65e0\u6b62\u5883\u5730\u8bad\u7ec3\u4e0b\u53bb\u3002\u81f3\u4e8e\u53cd\u5e94\u7ec3\u4e60\u80fd\u5e7f\u6cdb\u78e8\u5feb\u5fc3\u667a\u3001\u63d0\u5347\u667a\u529b\u6216\u9884\u9632\u8ba4\u77e5\u8870\u9000\u7684\u8bf4\u6cd5\u5219\u5f88\u8584\u5f31\u3001\u57fa\u672c\u672a\u83b7\u8bc1\u5b9e\uff1b\u8d85\u51fa\u53d7\u8bad\u4efb\u52a1\u4e4b\u5916\u7684\u8fc1\u79fb\u662f\u4f8b\u5916\uff0c\u800c\u975e\u5e38\u6001\u3002\u4f60\u6bcf\u5929\u7684\u6210\u7ee9\u4e5f\u662f\u7761\u7720\u3001\u8b66\u89c9\u5ea6\u548c\u75b2\u52b3\u7684\u4e00\u4e2a\u654f\u611f\u8bfb\u6570\u3002",rec:"\u628a\u4f60\u5728\u8bb8\u591a\u6b21\u8bd5\u9a8c\u4e0a\u7684\u5e73\u5747\u503c\u5f53\u4f5c\u771f\u6b63\u7684\u8861\u91cf\u6807\u51c6\uff0c\u5e76\u628a\u72b6\u6001\u7cdf\u7cd5\u7684\u4e00\u5929\u5f53\u6210\u4e00\u4e2a\u4fe1\u53f7\uff0c\u53bb\u68c0\u67e5\u4f60\u7684\u7761\u7720\uff0c\u800c\u4e0d\u662f\u66f4\u62fc\u547d\u5730\u786c\u5237\u3002",faq:[["\u6211\u771f\u7684\u80fd\u8ba9\u81ea\u5df1\u7684\u53cd\u5e94\u65f6\u53d8\u5feb\u5417\uff1f","\u80fd\uff0c\u4f46\u6709\u9650\u5ea6\u3002\u7ec3\u4e60\u4f1a\u524a\u51cf\u62a2\u8dd1\u548c\u8d70\u795e\uff0c\u8ba9\u4f60\u7684\u5e73\u5747\u503c\u6539\u5584\uff0c\u53ef\u4f60\u6700\u5feb\u53ef\u80fd\u7684\u53cd\u5e94\u5728\u5f88\u5927\u7a0b\u5ea6\u4e0a\u88ab\u795e\u7ecf\u548c\u5927\u8111\u7684\u52a0\u5de5\u901f\u5ea6\u5c01\u9876\uff0c\u8bad\u7ec3\u65e0\u6cd5\u628a\u5b83\u65e0\u6b62\u5883\u5730\u538b\u4f4e\u3002"],["\u600e\u6837\u7684\u7b80\u5355\u53cd\u5e94\u65f6\u7b97\u597d\uff1f","\u5bf9\u4e00\u4e2a\u5065\u5eb7\u7684\u6210\u5e74\u4eba\u6765\u8bf4\uff0c\u89c6\u89c9\u7b80\u5355\u53cd\u5e94\u5927\u81f4\u843d\u5728200\u5230250\u6beb\u79d2\u4e0a\u4e0b\u3002\u5bf9\u4efb\u4f55\u5355\u4e00\u6570\u5b57\u90fd\u8981\u8c28\u614e\u770b\u5f85\u2014\u2014\u75b2\u52b3\u3001\u7761\u7720\u3001\u5496\u5561\u56e0\u4ee5\u53ca\u4f60\u4f7f\u7528\u7684\u8bbe\u5907\u90fd\u4f1a\u8ba9\u5b83\u53d1\u751f\u53d8\u5316\u3002"],["\u8fd9\u4f1a\u8ba9\u6211\u66f4\u806a\u660e\uff0c\u6216\u6210\u4e3a\u66f4\u597d\u7684\u53f8\u673a\u5417\uff1f","\u522b\u6307\u671b\u6709\u5e7f\u6cdb\u7684\u5ef6\u7eed\u6548\u5e94\u3002\u4f60\u4f1a\u5728\u8fd9\u4e2a\u4efb\u52a1\u4e0a\u53d8\u5f97\u66f4\u5feb\uff0c\u4f46\u53cd\u5e94\u7ec3\u4e60\u80fd\u63d0\u5347\u4e00\u822c\u667a\u529b\u6216\u50cf\u5f00\u8f66\u8fd9\u6837\u7684\u73b0\u5b9e\u6280\u80fd\u7684\u8bc1\u636e\u5f88\u8584\u5f31\uff0c\u6240\u4ee5\u628a\u5b83\u5f53\u4f5c\u53cd\u5e94\u7ec3\u4e60\u6765\u770b\u5f85\uff0c\u800c\u4e0d\u662f\u4e00\u6b21\u5927\u8111\u5347\u7ea7\u3002"]],variants:"\u5404\u79cd\u53d8\u4f53\u5305\u62ec\u9009\u62e9\u53cd\u5e94\u65f6\uff08\u5728\u51e0\u4e2a\u76ee\u6807\u4e2d\u6311\u51fa\u6b63\u786e\u7684\u53cd\u5e94\uff09\u3001go/no-go\u4efb\u52a1\uff08\u5bf9\u67d0\u4e9b\u63d0\u793a\u8981\u884c\u52a8\uff0c\u5bf9\u53e6\u4e00\u4e9b\u8981\u514b\u5236\uff09\u3001\u7528\u58f0\u97f3\u800c\u975e\u89c6\u89c9\u4fe1\u53f7\uff0c\u4ee5\u53ca\u300e\u6253\u76ee\u6807\u300f\u7248\u672c\u2014\u2014\u76ee\u6807\u8fd8\u4f1a\u79fb\u52a8\uff0c\u4ece\u800c\u52a0\u5165\u7784\u51c6\u7684\u6210\u5206\u3002"}},"tower-london":{ru:{about:"\u0411\u0430\u0448\u043d\u044f \u041b\u043e\u043d\u0434\u043e\u043d\u0430 \u2014 \u044d\u0442\u043e \u0433\u043e\u043b\u043e\u0432\u043e\u043b\u043e\u043c\u043a\u0430 \u043d\u0430 \u043f\u043b\u0430\u043d\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u0435: \u0442\u0440\u0438 \u0446\u0432\u0435\u0442\u043d\u044b\u0445 \u0448\u0430\u0440\u0438\u043a\u0430 \u0441\u0442\u043e\u044f\u0442 \u043d\u0430 \u0442\u0440\u0451\u0445 \u0441\u0442\u0435\u0440\u0436\u043d\u044f\u0445 \u0440\u0430\u0437\u043d\u043e\u0439 \u0432\u043c\u0435\u0441\u0442\u0438\u043c\u043e\u0441\u0442\u0438 (\u043d\u0430 \u043e\u0434\u0438\u043d, \u0434\u0432\u0430 \u0438 \u0442\u0440\u0438 \u0448\u0430\u0440\u0438\u043a\u0430). \u0412\u0430\u043c \u043f\u043e\u043a\u0430\u0437\u044b\u0432\u0430\u044e\u0442 \u0446\u0435\u043b\u0435\u0432\u0443\u044e \u0440\u0430\u0441\u0441\u0442\u0430\u043d\u043e\u0432\u043a\u0443, \u0438 \u043d\u0443\u0436\u043d\u043e \u0437\u0430 \u043c\u0438\u043d\u0438\u043c\u0430\u043b\u044c\u043d\u043e\u0435 \u0447\u0438\u0441\u043b\u043e \u0445\u043e\u0434\u043e\u0432 \u043f\u0435\u0440\u0435\u0441\u0442\u0430\u0432\u0438\u0442\u044c \u0448\u0430\u0440\u0438\u043a\u0438, \u0434\u0432\u0438\u0433\u0430\u044f \u043f\u043e \u043e\u0434\u043d\u043e\u043c\u0443 \u0438 \u0442\u043e\u043b\u044c\u043a\u043e \u0432\u0435\u0440\u0445\u043d\u0438\u0439 \u043d\u0430 \u0441\u0442\u0435\u0440\u0436\u043d\u0435, \u043f\u043e\u043a\u0430 \u0432\u0430\u0448\u0430 \u0434\u043e\u0441\u043a\u0430 \u043d\u0435 \u0441\u043e\u0432\u043f\u0430\u0434\u0451\u0442 \u0441 \u043e\u0431\u0440\u0430\u0437\u0446\u043e\u043c.",benefit:"\u0422\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u043f\u043b\u0430\u043d\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u0435 \u0438 \u043f\u0440\u043e\u0441\u0447\u0451\u0442 \u043d\u0430\u043f\u0435\u0440\u0451\u0434: \u0443\u0434\u0435\u0440\u0436\u0430\u0442\u044c \u0446\u0435\u043b\u044c \u0432 \u0433\u043e\u043b\u043e\u0432\u0435, \u043c\u044b\u0441\u043b\u0435\u043d\u043d\u043e \u043f\u0440\u043e\u0438\u0433\u0440\u0430\u0442\u044c \u0432\u0441\u044e \u0446\u0435\u043f\u043e\u0447\u043a\u0443 \u0445\u043e\u0434\u043e\u0432 \u0434\u043e \u0442\u043e\u0433\u043e, \u043a\u0430\u043a \u0442\u0440\u043e\u043d\u0435\u0448\u044c \u0448\u0430\u0440\u0438\u043a, \u0438 \u0443\u0434\u0435\u0440\u0436\u0430\u0442\u044c\u0441\u044f \u043e\u0442 \u043e\u0447\u0435\u0432\u0438\u0434\u043d\u043e\u0433\u043e \u043f\u0435\u0440\u0432\u043e\u0433\u043e \u0445\u043e\u0434\u0430, \u0432\u0435\u0434\u0443\u0449\u0435\u0433\u043e \u0432 \u0442\u0443\u043f\u0438\u043a. \u0417\u0430\u043e\u0434\u043d\u043e \u0440\u0430\u0431\u043e\u0442\u0430\u044e\u0442 \u0440\u0430\u0431\u043e\u0447\u0430\u044f \u043f\u0430\u043c\u044f\u0442\u044c \u0438 \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044c \u0438\u043c\u043f\u0443\u043b\u044c\u0441\u0430.",history:"\u041e\u043d\u0430 \u0432\u044b\u0440\u043e\u0441\u043b\u0430 \u043d\u0435 \u0438\u0437 \u0438\u0433\u0440, \u0430 \u0438\u0437 \u043a\u043b\u0438\u043d\u0438\u0447\u0435\u0441\u043a\u043e\u0439 \u043d\u0435\u0439\u0440\u043e\u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u0438. \u0422\u0438\u043c \u0428\u0435\u043b\u043b\u0438\u0441 \u043f\u0440\u0435\u0434\u043b\u043e\u0436\u0438\u043b \u0435\u0451 \u0432 1982 \u0433\u043e\u0434\u0443, \u0447\u0442\u043e\u0431\u044b \u0438\u0437\u043c\u0435\u0440\u044f\u0442\u044c \u043d\u0430\u0440\u0443\u0448\u0435\u043d\u0438\u044f \u043f\u043b\u0430\u043d\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u044f \u0443 \u043f\u0430\u0446\u0438\u0435\u043d\u0442\u043e\u0432 \u0441 \u043f\u043e\u0440\u0430\u0436\u0435\u043d\u0438\u0435\u043c \u043b\u043e\u0431\u043d\u044b\u0445 \u0434\u043e\u043b\u0435\u0439; \u0437\u0430\u0434\u0430\u0447\u0443 \u0431\u044b\u0441\u0442\u0440\u043e \u0432\u0437\u044f\u043b\u0438 \u043d\u0430 \u0432\u043e\u043e\u0440\u0443\u0436\u0435\u043d\u0438\u0435 \u0432 \u0442\u0435\u0441\u0442\u043e\u0432\u044b\u0445 \u0431\u0430\u0442\u0430\u0440\u0435\u044f\u0445, \u043e\u043d\u0430 \u0441\u0442\u0430\u043b\u0430 \u043a\u043b\u0430\u0441\u0441\u0438\u043a\u043e\u0439 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u0439 \u043f\u0440\u0435\u0444\u0440\u043e\u043d\u0442\u0430\u043b\u044c\u043d\u043e\u0439 \u043a\u043e\u0440\u044b \u043d\u0430 \u0442\u043e\u043c\u043e\u0433\u0440\u0430\u0444\u0435 \u0438 \u0440\u0430\u0437\u043e\u0448\u043b\u0430\u0441\u044c \u043f\u043e \u043f\u0440\u0438\u043b\u043e\u0436\u0435\u043d\u0438\u044f\u043c \u0438 \u0441\u0431\u043e\u0440\u043d\u0438\u043a\u0430\u043c \u0442\u0440\u0435\u043d\u0430\u0436\u0451\u0440\u043e\u0432.",creator:"\u0410\u0432\u0442\u043e\u0440 \u2014 \u0431\u0440\u0438\u0442\u0430\u043d\u0441\u043a\u0438\u0439 \u043d\u0435\u0439\u0440\u043e\u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433 \u0422\u0438\u043c \u0428\u0435\u043b\u043b\u0438\u0441, 1982 \u0433\u043e\u0434, \u0441\u0442\u0430\u0442\u044c\u044f Specific impairments of planning \u0432 Philosophical Transactions of the Royal Society of London. \u042d\u0442\u043e \u043d\u0430\u043c\u0435\u0440\u0435\u043d\u043d\u043e\u0435 \u0443\u043f\u0440\u043e\u0449\u0435\u043d\u0438\u0435 \u0431\u043e\u043b\u0435\u0435 \u0441\u0442\u0430\u0440\u043e\u0439 \u0433\u043e\u043b\u043e\u0432\u043e\u043b\u043e\u043c\u043a\u0438 \u0425\u0430\u043d\u043e\u0439\u0441\u043a\u0430\u044f \u0431\u0430\u0448\u043d\u044f, \u043e\u043f\u0443\u0431\u043b\u0438\u043a\u043e\u0432\u0430\u043d\u043d\u043e\u0439 \u0444\u0440\u0430\u043d\u0446\u0443\u0437\u0441\u043a\u0438\u043c \u043c\u0430\u0442\u0435\u043c\u0430\u0442\u0438\u043a\u043e\u043c \u042d\u0434\u0443\u0430\u0440\u0434\u043e\u043c \u041b\u044e\u043a\u0430 \u0432 1883 \u0433\u043e\u0434\u0443.",methods:"\u041f\u0440\u043e\u0434\u0443\u043c\u044b\u0432\u0430\u0439\u0442\u0435 \u0432\u0441\u044e \u0446\u0435\u043f\u043e\u0447\u043a\u0443 \u0434\u043e \u043f\u0435\u0440\u0432\u043e\u0433\u043e \u0445\u043e\u0434\u0430, \u0430 \u043d\u0435 \u0434\u0432\u0438\u0433\u0430\u0439\u0442\u0435 \u0448\u0430\u0440\u0438\u043a\u0438 \u043d\u0430\u0443\u0433\u0430\u0434. \u0418\u0434\u0438\u0442\u0435 \u043e\u0442 \u0446\u0435\u043b\u0438 \u043d\u0430\u0437\u0430\u0434: \u043a\u0430\u043a\u043e\u0439 \u0448\u0430\u0440\u0438\u043a \u0434\u043e\u043b\u0436\u0435\u043d \u043e\u043a\u0430\u0437\u0430\u0442\u044c\u0441\u044f \u0432\u043d\u0438\u0437\u0443 \u043a\u0430\u0436\u0434\u043e\u0433\u043e \u0441\u0442\u0435\u0440\u0436\u043d\u044f, \u0438 \u0433\u0434\u0435 \u043d\u0435 \u043e\u0431\u043e\u0439\u0442\u0438\u0441\u044c \u0431\u0435\u0437 \u0445\u043e\u0434\u0430, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u0432\u0440\u0435\u043c\u0435\u043d\u043d\u043e \u0443\u0432\u043e\u0434\u0438\u0442 \u043e\u0442 \u043e\u0431\u0440\u0430\u0437\u0446\u0430. \u0421\u0432\u0435\u0440\u044f\u0439\u0442\u0435 \u0441\u0432\u043e\u0439 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442 \u0441 \u043c\u0438\u043d\u0438\u043c\u0430\u043b\u044c\u043d\u044b\u043c \u0447\u0438\u0441\u043b\u043e\u043c \u0445\u043e\u0434\u043e\u0432 \u0434\u043b\u044f \u043a\u0430\u0436\u0434\u043e\u0439 \u0437\u0430\u0434\u0430\u0447\u0438 \u2014 \u044d\u0442\u043e \u0434\u0435\u0440\u0436\u0438\u0442 \u0432 \u0442\u043e\u043d\u0443\u0441\u0435.",duration:"\u041b\u0443\u0447\u0448\u0435 \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u043c\u0438 \u0441\u043e\u0431\u0440\u0430\u043d\u043d\u044b\u043c\u0438 \u043f\u043e\u0434\u0445\u043e\u0434\u0430\u043c\u0438: \u043f\u044f\u0442\u044c-\u0434\u0435\u0441\u044f\u0442\u044c \u043c\u0438\u043d\u0443\u0442, \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0437\u0430\u0434\u0430\u0447 \u043f\u043e \u043d\u0430\u0440\u0430\u0441\u0442\u0430\u044e\u0449\u0435\u0439, \u043f\u0430\u0440\u0443-\u0442\u0440\u043e\u0439\u043a\u0443 \u0440\u0430\u0437 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e. \u041d\u0430\u0433\u0440\u0443\u0437\u043a\u0430 \u0442\u044f\u0436\u0451\u043b\u0430\u044f, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u043a\u0430\u0447\u0435\u0441\u0442\u0432\u043e \u043f\u043b\u0430\u043d\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u044f \u0432\u0430\u0436\u043d\u0435\u0435 \u043e\u0431\u044a\u0451\u043c\u0430, \u0438 \u043d\u0435\u0442 \u0441\u043c\u044b\u0441\u043b\u0430 \u043c\u043e\u043b\u043e\u0442\u0438\u0442\u044c \u0435\u0451 \u0447\u0430\u0441 \u043f\u043e\u0434\u0440\u044f\u0434.",research:"\u041d\u0430\u0434\u0451\u0436\u043d\u043e \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043d\u043e \u0443\u0437\u043a\u043e\u0435: \u0447\u0435\u043b\u043e\u0432\u0435\u043a \u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u0441\u044f \u043b\u0443\u0447\u0448\u0435 \u0438\u043c\u0435\u043d\u043d\u043e \u0432 \u0411\u0430\u0448\u043d\u0435 \u041b\u043e\u043d\u0434\u043e\u043d\u0430, \u0438 \u0441\u0430\u043c\u0430 \u0437\u0430\u0434\u0430\u0447\u0430 \u2014 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043b\u044c\u043d\u043e \u0447\u0443\u0432\u0441\u0442\u0432\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0439 \u043a\u043b\u0438\u043d\u0438\u0447\u0435\u0441\u043a\u0438\u0439 \u0438\u0437\u043c\u0435\u0440\u0438\u0442\u0435\u043b\u044c \u043f\u043b\u0430\u043d\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u044f, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u043f\u0440\u043e\u0441\u0435\u0434\u0430\u0435\u0442 \u043f\u0440\u0438 \u043f\u043e\u0440\u0430\u0436\u0435\u043d\u0438\u0438 \u043f\u0440\u0435\u0444\u0440\u043e\u043d\u0442\u0430\u043b\u044c\u043d\u043e\u0439 \u043a\u043e\u0440\u044b \u0438 \u043f\u0440\u0438 \u0440\u044f\u0434\u0435 \u0441\u043e\u0441\u0442\u043e\u044f\u043d\u0438\u0439. \u0420\u0430\u0441\u0445\u043e\u0436\u0438\u0439 \u0441\u043a\u0430\u0447\u043e\u043a \u043e\u0442 \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0438 \u043a \u0432 \u0446\u0435\u043b\u043e\u043c \u0431\u043e\u043b\u0435\u0435 \u0447\u0451\u0442\u043a\u043e\u043c\u0443 \u043f\u043b\u0430\u043d\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u044e \u0432 \u0436\u0438\u0437\u043d\u0438, \u043a \u0440\u043e\u0441\u0442\u0443 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442\u0430 \u0438\u043b\u0438 \u043a \u0437\u0430\u0449\u0438\u0442\u0435 \u043e\u0442 \u043a\u043e\u0433\u043d\u0438\u0442\u0438\u0432\u043d\u043e\u0433\u043e \u0441\u043f\u0430\u0434\u0430 \u043f\u043e\u0434\u043a\u0440\u0435\u043f\u043b\u0451\u043d \u0441\u043b\u0430\u0431\u043e \u0438 \u0432 \u043e\u0441\u043d\u043e\u0432\u043d\u043e\u043c \u043d\u0435 \u0434\u043e\u043a\u0430\u0437\u0430\u043d, \u0442\u0430\u043a \u0447\u0442\u043e \u043a \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f\u043c \u0448\u0438\u0440\u043e\u043a\u043e\u0433\u043e \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0430 \u0441\u0442\u043e\u0438\u0442 \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u044c\u0441\u044f \u043e\u0441\u0442\u043e\u0440\u043e\u0436\u043d\u043e.",rec:"\u041e\u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u0435\u0441\u044c \u0438 \u043f\u0440\u043e\u043b\u043e\u0436\u0438\u0442\u0435 \u0432\u0435\u0441\u044c \u043c\u0430\u0440\u0448\u0440\u0443\u0442 \u0432 \u0433\u043e\u043b\u043e\u0432\u0435 \u0434\u043e \u043f\u0435\u0440\u0432\u043e\u0433\u043e \u0445\u043e\u0434\u0430, \u043f\u043e\u0442\u043e\u043c \u0432\u044b\u043f\u043e\u043b\u043d\u0438\u0442\u0435 \u0431\u0435\u0437 \u043c\u0435\u0442\u0430\u043d\u0438\u0439 \u0438 \u0442\u043e\u043b\u044c\u043a\u043e \u0437\u0430\u0442\u0435\u043c \u043f\u043e\u0441\u043c\u043e\u0442\u0440\u0438\u0442\u0435, \u043d\u0430\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0431\u043b\u0438\u0437\u043a\u043e \u0432\u044b \u043e\u043a\u0430\u0437\u0430\u043b\u0438\u0441\u044c \u043a \u043c\u0438\u043d\u0438\u043c\u0443\u043c\u0443.",faq:[["\u0411\u0430\u0448\u043d\u044f \u041b\u043e\u043d\u0434\u043e\u043d\u0430 \u0438 \u0425\u0430\u043d\u043e\u0439\u0441\u043a\u0430\u044f \u0431\u0430\u0448\u043d\u044f \u2014 \u044d\u0442\u043e \u043e\u0434\u043d\u043e \u0438 \u0442\u043e \u0436\u0435?","\u041d\u0435\u0442. \u0412 \u0425\u0430\u043d\u043e\u0439\u0441\u043a\u043e\u0439 \u0431\u0430\u0448\u043d\u0435 \u0434\u0438\u0441\u043a\u0438 \u0440\u0430\u0437\u043d\u043e\u0433\u043e \u0440\u0430\u0437\u043c\u0435\u0440\u0430, \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u0432\u0441\u0435\u0433\u0434\u0430 \u0434\u043e\u043b\u0436\u043d\u044b \u043b\u0435\u0436\u0430\u0442\u044c \u043f\u043e \u0443\u0431\u044b\u0432\u0430\u043d\u0438\u044e, \u0430 \u0432 \u0411\u0430\u0448\u043d\u0435 \u041b\u043e\u043d\u0434\u043e\u043d\u0430 \u0448\u0430\u0440\u0438\u043a\u0438 \u043e\u0434\u0438\u043d\u0430\u043a\u043e\u0432\u043e\u0433\u043e \u0440\u0430\u0437\u043c\u0435\u0440\u0430 \u0438 \u0441\u0442\u0435\u0440\u0436\u043d\u0438 \u0432\u043c\u0435\u0449\u0430\u044e\u0442 \u0442\u043e\u043b\u044c\u043a\u043e \u043e\u0434\u0438\u043d, \u0434\u0432\u0430 \u0438\u043b\u0438 \u0442\u0440\u0438 \u0448\u0430\u0440\u0438\u043a\u0430. \u0412\u043d\u0435\u0448\u043d\u0435 \u043f\u043e\u0445\u043e\u0436\u0438, \u043d\u043e \u043d\u0430\u0433\u0440\u0443\u0436\u0430\u044e\u0442 \u043f\u043b\u0430\u043d\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u0435 \u043d\u0435\u043c\u043d\u043e\u0433\u043e \u043f\u043e-\u0440\u0430\u0437\u043d\u043e\u043c\u0443."],["\u0415\u0441\u043b\u0438 \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u0430\u0442\u044c\u0441\u044f, \u044f \u043d\u0430\u0447\u043d\u0443 \u043b\u0443\u0447\u0448\u0435 \u043f\u043b\u0430\u043d\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u0432 \u0440\u0435\u0430\u043b\u044c\u043d\u043e\u0439 \u0436\u0438\u0437\u043d\u0438?","\u0412 \u0441\u0430\u043c\u043e\u0439 \u0433\u043e\u043b\u043e\u0432\u043e\u043b\u043e\u043c\u043a\u0435 \u0432\u044b \u0432\u044b\u0440\u0430\u0441\u0442\u0435\u0442\u0435 \u043d\u0430\u0434\u0451\u0436\u043d\u043e, \u0438 \u044d\u0442\u043e \u0443\u0432\u0430\u0436\u0430\u0435\u043c\u044b\u0439 \u043a\u043b\u0438\u043d\u0438\u0447\u0435\u0441\u043a\u0438\u0439 \u0442\u0435\u0441\u0442 \u043f\u043b\u0430\u043d\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u044f. \u041d\u043e \u0443\u0431\u0435\u0434\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u0433\u043e \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0430 \u043d\u0430 \u0442\u043e, \u043a\u0430\u043a \u0432\u044b \u043e\u0440\u0433\u0430\u043d\u0438\u0437\u0443\u0435\u0442\u0435 \u0434\u0435\u043d\u044c \u0438\u043b\u0438 \u043f\u0440\u043e\u0435\u043a\u0442\u044b, \u043d\u0435 \u043f\u043e\u043a\u0430\u0437\u0430\u043d\u043e, \u0442\u0430\u043a \u0447\u0442\u043e \u0432\u043e\u0441\u043f\u0440\u0438\u043d\u0438\u043c\u0430\u0439\u0442\u0435 \u0435\u0451 \u043a\u0430\u043a \u0441\u043e\u0431\u0440\u0430\u043d\u043d\u0443\u044e \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0443, \u0430 \u043d\u0435 \u043a\u0430\u043a \u0433\u0430\u0440\u0430\u043d\u0442\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u044b\u0439 \u0430\u043f\u0433\u0440\u0435\u0439\u0434 \u0436\u0438\u0437\u043d\u0438."],["\u0427\u0442\u043e \u0441\u0447\u0438\u0442\u0430\u0442\u044c \u0445\u043e\u0440\u043e\u0448\u0438\u043c \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442\u043e\u043c?","\u0420\u0435\u0448\u0438\u0442\u044c \u043a\u0430\u0436\u0434\u0443\u044e \u0434\u043e\u0441\u043a\u0443 \u0437\u0430 \u043c\u0438\u043d\u0438\u043c\u0430\u043b\u044c\u043d\u043e\u0435 \u0447\u0438\u0441\u043b\u043e \u0445\u043e\u0434\u043e\u0432, \u043f\u0440\u0438\u0447\u0451\u043c \u043f\u0440\u043e\u0434\u0443\u043c\u0430\u0432 \u0446\u0435\u043f\u043e\u0447\u043a\u0443 \u0432 \u0433\u043e\u043b\u043e\u0432\u0435, \u0430 \u043d\u0435 \u043f\u0435\u0440\u0435\u0431\u043e\u0440\u043e\u043c. \u041f\u043e\u0442\u0440\u0430\u0442\u0438\u0442\u044c \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0441\u0435\u043a\u0443\u043d\u0434 \u043d\u0430 \u043e\u0431\u0434\u0443\u043c\u044b\u0432\u0430\u043d\u0438\u0435 \u043f\u0435\u0440\u0435\u0434 \u043f\u0435\u0440\u0432\u044b\u043c \u0445\u043e\u0434\u043e\u043c \u0438 \u043f\u043e\u0447\u0442\u0438 \u043d\u0435 \u0438\u0441\u043f\u0440\u0430\u0432\u043b\u044f\u0442\u044c\u0441\u044f \u2014 \u043b\u0443\u0447\u0448\u0438\u0439 \u043f\u0440\u0438\u0437\u043d\u0430\u043a, \u0447\u0435\u043c \u0431\u044b\u0441\u0442\u0440\u0430\u044f \u0441\u0443\u0435\u0442\u043b\u0438\u0432\u0430\u044f \u043f\u0435\u0440\u0435\u0441\u0442\u0430\u043d\u043e\u0432\u043a\u0430."]],variants:"\u0411\u043b\u0438\u0437\u043a\u0430\u044f \u0440\u043e\u0434\u043d\u044f \u2014 \u0425\u0430\u043d\u043e\u0439\u0441\u043a\u0430\u044f \u0431\u0430\u0448\u043d\u044f (\u0434\u0438\u0441\u043a\u0438 \u043f\u043e \u0440\u0430\u0437\u043c\u0435\u0440\u0443 \u0432\u043c\u0435\u0441\u0442\u043e \u0441\u0442\u0435\u0440\u0436\u043d\u0435\u0439 \u043e\u0433\u0440\u0430\u043d\u0438\u0447\u0435\u043d\u043d\u043e\u0439 \u0432\u043c\u0435\u0441\u0442\u0438\u043c\u043e\u0441\u0442\u0438), Stockings of Cambridge \u0438\u0437 \u0431\u0430\u0442\u0430\u0440\u0435\u0438 CANTAB, Drexel-\u0432\u0435\u0440\u0441\u0438\u044f (ToL-DX), Tower Test \u0432 \u0441\u043e\u0441\u0442\u0430\u0432\u0435 D-KEFS \u0438 \u0444\u0440\u0430\u0439\u0431\u0443\u0440\u0433\u0441\u043a\u0430\u044f TOL-F. \u0412\u0430\u0440\u0438\u0430\u043d\u0442\u044b \u0440\u0430\u0437\u043b\u0438\u0447\u0430\u044e\u0442\u0441\u044f \u0447\u0438\u0441\u043b\u043e\u043c \u0448\u0430\u0440\u0438\u043a\u043e\u0432 \u0438\u043b\u0438 \u0434\u0438\u0441\u043a\u043e\u0432, \u0440\u0430\u0441\u0441\u0442\u0430\u043d\u043e\u0432\u043a\u043e\u0439 \u0441\u0442\u0435\u0440\u0436\u043d\u0435\u0439 \u0438 \u0442\u0435\u043c, \u043d\u0430\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0441\u0442\u0440\u043e\u0433\u043e \u0432\u0440\u0435\u043c\u044f \u043d\u0430 \u043e\u0431\u0434\u0443\u043c\u044b\u0432\u0430\u043d\u0438\u0435 \u043e\u0442\u0434\u0435\u043b\u044f\u044e\u0442 \u043e\u0442 \u0432\u0440\u0435\u043c\u0435\u043d\u0438 \u043d\u0430 \u0438\u0441\u043f\u043e\u043b\u043d\u0435\u043d\u0438\u0435."},en:{about:"The Tower of London is a planning puzzle with three coloured balls sitting on three pegs that hold a different number of balls (one, two and three). You are shown a goal arrangement and have to move the balls, one at a time and only the topmost ball on a peg, until your board matches the goal in as few moves as possible.",benefit:"It exercises planning and look-ahead: holding a goal in mind, mentally simulating a sequence of moves before you touch anything, and resisting the obvious first move when it leads to a dead end. Working memory and impulse control come along for the ride.",history:"It grew out of clinical neuropsychology rather than games. Tim Shallice introduced it in 1982 to measure planning deficits in patients with frontal-lobe damage, and it was quickly picked up by test batteries, became a fixture in brain-imaging studies of the prefrontal cortex, and spread into apps and brain-training collections.",creator:"Created by the British neuropsychologist Tim Shallice in 1982, in his paper Specific impairments of planning (Philosophical Transactions of the Royal Society of London). It is a deliberate simplification of the older Tower of Hanoi puzzle, which the French mathematician Edouard Lucas published in 1883.",methods:"Plan the whole sequence before your first move rather than nudging balls and hoping. Work backwards from the goal, ask which ball must end up on the bottom of each peg, and watch for moves that temporarily take you further from the goal but are unavoidable. Tracking the minimum-move count for each puzzle keeps you honest.",duration:"Short focused sets work best: five to ten minutes, a few puzzles of rising difficulty, a few times a week. It is mentally taxing, so quality of planning matters far more than volume, and there is little point grinding it for an hour.",research:"What is solidly shown is narrow: people get better at the Tower of London itself, and the task is a genuinely sensitive clinical measure of planning that is impaired after prefrontal damage and in several conditions. The popular leap from practising it to broadly sharper everyday planning, higher intelligence or protection against cognitive decline is weak and largely unproven, so treat far-reaching transfer claims with caution.",rec:"Pause and plan the full route in your head before the first move, then execute without second-guessing, and only then check how close you came to the minimum.",faq:[["Is the Tower of London the same as the Tower of Hanoi?","No. The Tower of Hanoi uses discs of different sizes that must always stay in size order, while the Tower of London uses same-sized balls and pegs that hold only one, two or three balls. They look alike but stress planning in slightly different ways."],["Will practising this make me better at planning in real life?","It reliably makes you better at the puzzle, and it is a respected clinical test of planning. But strong carry-over to organising your day or projects has not been convincingly demonstrated, so enjoy it as focused practice rather than a guaranteed life upgrade."],["What counts as a good result?","Solving each board in the minimum number of moves, ideally after planning the sequence in your head rather than by trial and error. Taking a few seconds to think before the first move and then needing few corrections is a better sign than fast, frantic shuffling."]],variants:"Close relatives include the Tower of Hanoi (size-ordered discs instead of capacity-limited pegs), the Stockings of Cambridge in the CANTAB battery, the Drexel Tower of London (ToL-DX), the Tower Test in the D-KEFS, and the Freiburg TOL-F. Versions differ in the number of balls or discs, peg layout and how strictly planning time is separated from execution time."},es:{about:"La Torre de Londres es un puzle de planificaci\xf3n con tres bolas de colores apoyadas en tres clavijas que admiten un n\xfamero distinto de bolas (una, dos y tres). Se te muestra una disposici\xf3n objetivo y debes mover las bolas, de una en una y solo la bola superior de cada clavija, hasta que tu tablero coincida con el objetivo en el menor n\xfamero de movimientos posible.",benefit:"Ejercita la planificaci\xf3n y la anticipaci\xf3n: mantener un objetivo en mente, simular mentalmente una secuencia de movimientos antes de tocar nada y resistir el movimiento inicial obvio cuando lleva a un callej\xf3n sin salida. La memoria de trabajo y el control de los impulsos vienen de propina.",history:"Surgi\xf3 de la neuropsicolog\xeda cl\xednica m\xe1s que de los juegos. Tim Shallice lo introdujo en 1982 para medir los d\xe9ficits de planificaci\xf3n en pacientes con da\xf1o en el l\xf3bulo frontal, y enseguida lo adoptaron las bater\xedas de tests, se volvi\xf3 un elemento fijo en los estudios de neuroimagen de la corteza prefrontal y se extendi\xf3 a las apps y a las colecciones de entrenamiento mental.",creator:"Creado por el neuropsic\xf3logo brit\xe1nico Tim Shallice en 1982, en su art\xedculo Specific impairments of planning (Philosophical Transactions of the Royal Society of London). Es una simplificaci\xf3n deliberada del m\xe1s antiguo puzle de la Torre de Han\xf3i, que el matem\xe1tico franc\xe9s \xc9douard Lucas public\xf3 en 1883.",methods:"Planifica toda la secuencia antes de tu primer movimiento, en lugar de empujar bolas y confiar en la suerte. Trabaja hacia atr\xe1s desde el objetivo, preg\xfantate qu\xe9 bola debe acabar en el fondo de cada clavija y atento a los movimientos que temporalmente te alejan del objetivo pero son inevitables. Llevar la cuenta del n\xfamero m\xednimo de movimientos de cada puzle te mantiene honesto.",duration:"Los conjuntos cortos y concentrados funcionan mejor: de cinco a diez minutos, unos cuantos puzles de dificultad creciente, unas cuantas veces por semana. Es exigente mentalmente, as\xed que la calidad de la planificaci\xf3n importa mucho m\xe1s que el volumen, y tiene poco sentido machacarlo durante una hora.",research:"Lo que est\xe1 demostrado con solidez es estrecho: la gente mejora en la Torre de Londres en s\xed, y la tarea es una medida cl\xednica genuinamente sensible de la planificaci\xf3n, que se ve afectada tras un da\xf1o prefrontal y en varias condiciones. El salto popular de practicarla a una planificaci\xf3n cotidiana m\xe1s afilada en general, una mayor inteligencia o protecci\xf3n contra el deterioro cognitivo es d\xe9bil y en gran medida no est\xe1 probado, as\xed que toma con cautela las afirmaciones de transferencia de gran alcance.",rec:"Detente y planifica toda la ruta en tu cabeza antes del primer movimiento, luego ejecuta sin dudar, y solo entonces comprueba cu\xe1nto te acercaste al m\xednimo.",faq:[["\xbfLa Torre de Londres es lo mismo que la Torre de Han\xf3i?","No. La Torre de Han\xf3i usa discos de distintos tama\xf1os que siempre deben permanecer en orden de tama\xf1o, mientras que la Torre de Londres usa bolas del mismo tama\xf1o y clavijas que admiten solo una, dos o tres bolas. Se parecen, pero exigen la planificaci\xf3n de maneras algo distintas."],["\xbfPracticar esto me har\xe1 mejor planificando en la vida real?","Te hace mejor de forma fiable en el puzle, y es un respetado test cl\xednico de planificaci\xf3n. Pero no se ha demostrado de forma convincente un fuerte traslado a organizar tu d\xeda o tus proyectos, as\xed que disfr\xfatalo como pr\xe1ctica concentrada y no como una mejora garantizada para la vida."],["\xbfQu\xe9 cuenta como un buen resultado?","Resolver cada tablero en el n\xfamero m\xednimo de movimientos, idealmente tras planificar la secuencia en tu cabeza y no por ensayo y error. Tomarte unos segundos para pensar antes del primer movimiento y luego necesitar pocas correcciones es mejor se\xf1al que un trasiego r\xe1pido y fren\xe9tico."]],variants:"Entre sus parientes cercanos est\xe1n la Torre de Han\xf3i (discos ordenados por tama\xf1o en lugar de clavijas con capacidad limitada), las Medias de Cambridge de la bater\xeda CANTAB, la Torre de Londres de Drexel (ToL-DX), el Tower Test del D-KEFS y la TOL-F de Friburgo. Las versiones difieren en el n\xfamero de bolas o discos, la disposici\xf3n de las clavijas y con qu\xe9 rigor se separa el tiempo de planificaci\xf3n del de ejecuci\xf3n."},de:{about:"Der Tower of London ist ein Planungsr\xe4tsel mit drei farbigen Kugeln, die auf drei St\xe4ben sitzen, welche jeweils eine unterschiedliche Anzahl Kugeln fassen (eine, zwei und drei). Dir wird eine Zielanordnung gezeigt, und du musst die Kugeln einzeln bewegen \u2014 und immer nur die oberste Kugel eines Stabs \u2014, bis dein Brett dem Ziel in m\xf6glichst wenigen Z\xfcgen entspricht.",benefit:"Es trainiert das Planen und Vorausdenken: ein Ziel im Kopf zu behalten, eine Zugfolge gedanklich durchzuspielen, bevor du etwas anfasst, und dem naheliegenden ersten Zug zu widerstehen, wenn er in eine Sackgasse f\xfchrt. Arbeitsged\xe4chtnis und Impulskontrolle kommen ganz nebenbei mit dazu.",history:"Es entstand aus der klinischen Neuropsychologie und nicht aus dem Spielbereich. Tim Shallice f\xfchrte es 1982 ein, um Planungsdefizite bei Patienten mit Stirnlappensch\xe4digung zu messen, und es wurde rasch in Testbatterien \xfcbernommen, wurde zum festen Bestandteil bildgebender Studien zum pr\xe4frontalen Kortex und fand seinen Weg in Apps und Gehirntraining-Sammlungen.",creator:"Erschaffen vom britischen Neuropsychologen Tim Shallice im Jahr 1982 in seinem Aufsatz Specific impairments of planning (Philosophical Transactions of the Royal Society of London). Es ist eine bewusste Vereinfachung des \xe4lteren T\xfcrme-von-Hanoi-R\xe4tsels, das der franz\xf6sische Mathematiker \xc9douard Lucas 1883 ver\xf6ffentlichte.",methods:"Plane die gesamte Zugfolge vor deinem ersten Zug, statt die Kugeln zu verschieben und zu hoffen. Arbeite vom Ziel r\xfcckw\xe4rts, frage, welche Kugel ganz unten auf jedem Stab landen muss, und achte auf Z\xfcge, die dich vor\xfcbergehend weiter vom Ziel wegbringen, aber unvermeidlich sind. Die Mindestzugzahl jedes R\xe4tsels im Blick zu behalten, h\xe4lt dich ehrlich.",duration:"Kurze, konzentrierte S\xe4tze funktionieren am besten: f\xfcnf bis zehn Minuten, ein paar R\xe4tsel mit steigendem Schwierigkeitsgrad, ein paar Mal pro Woche. Es ist geistig anstrengend, also z\xe4hlt die Qualit\xe4t der Planung weit mehr als die Menge, und es bringt wenig, eine Stunde lang daran zu schuften.",research:"Solide belegt ist nur Enges: Menschen werden besser im Tower of London selbst, und die Aufgabe ist ein wirklich sensibles klinisches Ma\xdf f\xfcr Planung, die nach pr\xe4frontaler Sch\xe4digung und bei mehreren Krankheitsbildern beeintr\xe4chtigt ist. Der popul\xe4re Sprung vom \xdcben zu allgemein sch\xe4rferer Alltagsplanung, h\xf6herer Intelligenz oder Schutz vor kognitivem Abbau ist schwach und weitgehend unbelegt, also begegne weitreichenden Transferbehauptungen mit Vorsicht.",rec:"Halte inne und plane die ganze Route im Kopf vor dem ersten Zug, f\xfchre sie dann ohne Zweifeln aus, und pr\xfcfe erst danach, wie nah du am Minimum warst.",faq:[["Ist der Tower of London dasselbe wie die T\xfcrme von Hanoi?","Nein. Die T\xfcrme von Hanoi verwenden Scheiben unterschiedlicher Gr\xf6\xdfe, die stets in Gr\xf6\xdfenordnung bleiben m\xfcssen, w\xe4hrend der Tower of London gleich gro\xdfe Kugeln und St\xe4be verwendet, die nur eine, zwei oder drei Kugeln fassen. Sie sehen \xe4hnlich aus, fordern das Planen aber auf leicht unterschiedliche Weise."],["Macht mich das \xdcben besser im Planen im echten Leben?","Es macht dich zuverl\xe4ssig besser im R\xe4tsel, und es ist ein anerkannter klinischer Planungstest. Aber eine starke \xdcbertragung auf das Organisieren deines Tages oder deiner Projekte ist nicht \xfcberzeugend nachgewiesen, also genie\xdfe es als gezieltes Training statt als garantiertes Lebens-Upgrade."],["Was z\xe4hlt als gutes Ergebnis?","Jedes Brett in der Mindestzugzahl zu l\xf6sen, idealerweise nachdem du die Zugfolge im Kopf geplant hast statt durch Ausprobieren. Ein paar Sekunden vor dem ersten Zug nachzudenken und dann wenige Korrekturen zu brauchen, ist ein besseres Zeichen als schnelles, hektisches Hin-und-Herschieben."]],variants:"Nahe Verwandte sind die T\xfcrme von Hanoi (gr\xf6\xdfengeordnete Scheiben statt kapazit\xe4tsbegrenzter St\xe4be), die Stockings of Cambridge in der CANTAB-Batterie, der Drexel Tower of London (ToL-DX), der Tower Test im D-KEFS und der Freiburger TOL-F. Die Versionen unterscheiden sich in der Anzahl der Kugeln oder Scheiben, im St\xe4be-Aufbau und darin, wie streng die Planungszeit von der Ausf\xfchrungszeit getrennt wird."},pt:{about:"A Torre de Londres \xe9 um quebra-cabe\xe7a de planejamento com tr\xeas bolas coloridas apoiadas em tr\xeas pinos que comportam n\xfameros diferentes de bolas (um, dois e tr\xeas). Mostra-se a voc\xea um arranjo-alvo, e voc\xea precisa mover as bolas, uma de cada vez e apenas a bola do topo de cada pino, at\xe9 que seu tabuleiro coincida com o alvo no menor n\xfamero de movimentos poss\xedvel.",benefit:"Ele exercita o planejamento e a antecipa\xe7\xe3o: manter um objetivo na cabe\xe7a, simular mentalmente uma sequ\xeancia de movimentos antes de tocar em qualquer coisa e resistir ao movimento \xf3bvio quando ele leva a um beco sem sa\xedda. A mem\xf3ria de trabalho e o controle dos impulsos v\xe3o junto na carona.",history:"Ela nasceu da neuropsicologia cl\xednica, n\xe3o dos jogos. Tim Shallice a introduziu em 1982 para medir d\xe9ficits de planejamento em pacientes com les\xe3o no lobo frontal, e logo foi adotada por baterias de testes, virou presen\xe7a constante em estudos de neuroimagem do c\xf3rtex pr\xe9-frontal e se espalhou por aplicativos e cole\xe7\xf5es de treino cerebral.",creator:"Criada pelo neuropsic\xf3logo brit\xe2nico Tim Shallice em 1982, em seu artigo Specific impairments of planning (Philosophical Transactions of the Royal Society of London). \xc9 uma simplifica\xe7\xe3o deliberada do quebra-cabe\xe7a mais antigo Torre de Han\xf3i, que o matem\xe1tico franc\xeas \xc9douard Lucas publicou em 1883.",methods:"Planeje a sequ\xeancia inteira antes do primeiro movimento, em vez de empurrar bolas na esperan\xe7a de acertar. Trabalhe de tr\xe1s para frente a partir do alvo, pergunte qual bola precisa terminar no fundo de cada pino e fique atento a movimentos que temporariamente te afastam do alvo, mas s\xe3o inevit\xe1veis. Acompanhar o n\xfamero m\xednimo de movimentos de cada quebra-cabe\xe7a te mant\xe9m honesto.",duration:"Conjuntos curtos e focados funcionam melhor: de cinco a dez minutos, alguns quebra-cabe\xe7as de dificuldade crescente, algumas vezes por semana. \xc9 mentalmente exigente, ent\xe3o a qualidade do planejamento importa muito mais que o volume, e n\xe3o faz sentido insistir nela por uma hora.",research:"O que est\xe1 solidamente demonstrado \xe9 restrito: as pessoas ficam melhores na pr\xf3pria Torre de Londres, e a tarefa \xe9 uma medida cl\xednica genuinamente sens\xedvel de planejamento, prejudicada ap\xf3s les\xe3o pr\xe9-frontal e em diversas condi\xe7\xf5es. O salto popular de pratic\xe1-la para um planejamento do dia a dia amplamente mais afiado, mais intelig\xeancia ou prote\xe7\xe3o contra o decl\xednio cognitivo \xe9 fraco e em grande parte n\xe3o comprovado, ent\xe3o trate as alega\xe7\xf5es de transfer\xeancia ampla com cautela.",rec:"Pare e planeje o trajeto completo na cabe\xe7a antes do primeiro movimento, depois execute sem ficar duvidando, e s\xf3 ent\xe3o veja o qu\xe3o perto voc\xea chegou do m\xednimo.",faq:[["A Torre de Londres \xe9 a mesma coisa que a Torre de Han\xf3i?","N\xe3o. A Torre de Han\xf3i usa discos de tamanhos diferentes que precisam permanecer sempre em ordem de tamanho, enquanto a Torre de Londres usa bolas do mesmo tamanho e pinos que comportam apenas uma, duas ou tr\xeas bolas. Elas se parecem, mas exigem o planejamento de maneiras um pouco diferentes."],["Praticar isso vai me deixar melhor em planejar na vida real?","Ela te deixa de forma confi\xe1vel melhor no quebra-cabe\xe7a, e \xe9 um teste cl\xednico respeitado de planejamento. Mas uma transfer\xeancia forte para organizar seu dia ou seus projetos n\xe3o foi demonstrada de modo convincente, ent\xe3o aproveite-a como pr\xe1tica focada, e n\xe3o como uma melhoria de vida garantida."],["O que conta como um bom resultado?","Resolver cada tabuleiro no n\xfamero m\xednimo de movimentos, idealmente depois de planejar a sequ\xeancia na cabe\xe7a, e n\xe3o por tentativa e erro. Levar alguns segundos para pensar antes do primeiro movimento e ent\xe3o precisar de poucas corre\xe7\xf5es \xe9 um sinal melhor do que embaralhar r\xe1pido e de forma fren\xe9tica."]],variants:"Parentes pr\xf3ximos incluem a Torre de Han\xf3i (discos ordenados por tamanho, em vez de pinos com capacidade limitada), as Meias de Cambridge (Stockings of Cambridge) da bateria CANTAB, a Torre de Londres de Drexel (ToL-DX), o Teste da Torre na D-KEFS e a TOL-F de Freiburg. As vers\xf5es diferem no n\xfamero de bolas ou discos, na disposi\xe7\xe3o dos pinos e em qu\xe3o estritamente o tempo de planejamento \xe9 separado do tempo de execu\xe7\xe3o."},hi:{about:"Tower of London \u090f\u0915 \u092f\u094b\u091c\u0928\u093e \u092c\u0928\u093e\u0928\u0947 \u0935\u093e\u0932\u0940 \u092a\u0939\u0947\u0932\u0940 \u0939\u0948 \u091c\u093f\u0938\u092e\u0947\u0902 \u0924\u0940\u0928 \u0930\u0902\u0917\u0940\u0928 \u0917\u0947\u0902\u0926\u0947\u0902 \u0924\u0940\u0928 \u0916\u0942\u0901\u091f\u093f\u092f\u094b\u0902 \u092a\u0930 \u091f\u093f\u0915\u0940 \u0939\u094b\u0924\u0940 \u0939\u0948\u0902, \u0914\u0930 \u0939\u0930 \u0916\u0942\u0901\u091f\u0940 \u092a\u0930 \u0905\u0932\u0917-\u0905\u0932\u0917 \u0938\u0902\u0916\u094d\u092f\u093e \u092e\u0947\u0902 \u0917\u0947\u0902\u0926\u0947\u0902 \u0906 \u0938\u0915\u0924\u0940 \u0939\u0948\u0902 (\u090f\u0915, \u0926\u094b \u0914\u0930 \u0924\u0940\u0928)\u0964 \u0906\u092a\u0915\u094b \u090f\u0915 \u0932\u0915\u094d\u0937\u094d\u092f-\u0938\u091c\u093e\u0935\u091f \u0926\u093f\u0916\u093e\u0908 \u091c\u093e\u0924\u0940 \u0939\u0948 \u0914\u0930 \u0906\u092a\u0915\u094b \u0917\u0947\u0902\u0926\u094b\u0902 \u0915\u094b \u090f\u0915-\u090f\u0915 \u0915\u0930\u0915\u0947 \u2014 \u0914\u0930 \u0915\u0947\u0935\u0932 \u0915\u093f\u0938\u0940 \u0916\u0942\u0901\u091f\u0940 \u092a\u0930 \u0938\u092c\u0938\u0947 \u090a\u092a\u0930\u0940 \u0917\u0947\u0902\u0926 \u0915\u094b \u2014 \u0924\u092c \u0924\u0915 \u0938\u0930\u0915\u093e\u0928\u093e \u0939\u094b\u0924\u093e \u0939\u0948 \u091c\u092c \u0924\u0915 \u0906\u092a\u0915\u093e \u092c\u094b\u0930\u094d\u0921 \u0915\u092e \u0938\u0947 \u0915\u092e \u091a\u093e\u0932\u094b\u0902 \u092e\u0947\u0902 \u0932\u0915\u094d\u0937\u094d\u092f \u0938\u0947 \u092e\u0947\u0932 \u0928 \u0916\u093e \u091c\u093e\u090f\u0964",benefit:"\u092f\u0939 \u092f\u094b\u091c\u0928\u093e \u092c\u0928\u093e\u0928\u0947 \u0914\u0930 \u0906\u0917\u0947-\u0915\u0940-\u0938\u094b\u091a \u0915\u0940 \u0915\u0938\u0930\u0924 \u0915\u0930\u093e\u0924\u093e \u0939\u0948: \u0915\u093f\u0938\u0940 \u0932\u0915\u094d\u0937\u094d\u092f \u0915\u094b \u0926\u093f\u092e\u093e\u0917 \u092e\u0947\u0902 \u0925\u093e\u092e\u0947 \u0930\u0916\u0928\u093e, \u0915\u0941\u091b \u092d\u0940 \u091b\u0942\u0928\u0947 \u0938\u0947 \u092a\u0939\u0932\u0947 \u092e\u0928 \u0939\u0940 \u092e\u0928 \u091a\u093e\u0932\u094b\u0902 \u0915\u0947 \u0915\u094d\u0930\u092e \u0915\u0940 \u0928\u0915\u0932 \u091a\u0932\u093e\u0928\u093e, \u0914\u0930 \u091c\u092c \u0938\u092c\u0938\u0947 \u092a\u0939\u0932\u0947 \u0938\u0942\u091d\u0928\u0947 \u0935\u093e\u0932\u0940 \u091a\u093e\u0932 \u092c\u0902\u0926 \u0917\u0932\u0940 \u0915\u0940 \u0913\u0930 \u0932\u0947 \u091c\u093e\u090f \u0924\u094b \u0909\u0938\u0938\u0947 \u092c\u091a\u0928\u093e\u0964 \u0935\u0930\u094d\u0915\u093f\u0902\u0917 \u092e\u0947\u092e\u094b\u0930\u0940 \u0914\u0930 \u0906\u0935\u0947\u0917-\u0928\u093f\u092f\u0902\u0924\u094d\u0930\u0923 \u092d\u0940 \u0938\u093e\u0925-\u0938\u093e\u0925 \u091a\u0932\u0924\u0947 \u0939\u0948\u0902\u0964",history:"\u092f\u0939 \u0916\u0947\u0932\u094b\u0902 \u0938\u0947 \u0928\u0939\u0940\u0902, \u092c\u0932\u094d\u0915\u093f \u0928\u0948\u0926\u093e\u0928\u093f\u0915 \u0924\u0902\u0924\u094d\u0930\u093f\u0915\u093e-\u092e\u0928\u094b\u0935\u093f\u091c\u094d\u091e\u093e\u0928 \u0938\u0947 \u0928\u093f\u0915\u0932\u093e\u0964 Tim Shallice \u0928\u0947 \u0907\u0938\u0947 1982 \u092e\u0947\u0902 \u092b\u094d\u0930\u0902\u091f\u0932-\u0932\u094b\u092c \u0915\u094d\u0937\u0924\u093f \u0935\u093e\u0932\u0947 \u092e\u0930\u0940\u091c\u093c\u094b\u0902 \u092e\u0947\u0902 \u092f\u094b\u091c\u0928\u093e-\u0938\u0902\u092c\u0902\u0927\u0940 \u0915\u092e\u093f\u092f\u094b\u0902 \u0915\u094b \u092e\u093e\u092a\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u092a\u0947\u0936 \u0915\u093f\u092f\u093e, \u0914\u0930 \u0907\u0938\u0947 \u091c\u0932\u094d\u0926\u0940 \u0939\u0940 \u092a\u0930\u0940\u0915\u094d\u0937\u0923-\u0938\u092e\u0942\u0939\u094b\u0902 \u092e\u0947\u0902 \u0905\u092a\u0928\u093e \u0932\u093f\u092f\u093e \u0917\u092f\u093e, \u092f\u0939 \u092a\u094d\u0930\u0940\u092b\u094d\u0930\u0902\u091f\u0932 \u0915\u0949\u0930\u094d\u091f\u0947\u0915\u094d\u0938 \u0915\u0947 \u092e\u0938\u094d\u0924\u093f\u0937\u094d\u0915-\u091b\u0935\u093f \u0905\u0927\u094d\u092f\u092f\u0928\u094b\u0902 \u092e\u0947\u0902 \u090f\u0915 \u0928\u093f\u092f\u092e\u093f\u0924 \u0939\u093f\u0938\u094d\u0938\u093e \u092c\u0928 \u0917\u092f\u093e, \u0914\u0930 \u0910\u092a\u094d\u0938 \u0924\u0925\u093e \u0926\u093f\u092e\u093e\u0917\u0940-\u0915\u0938\u0930\u0924 \u0938\u0902\u0917\u094d\u0930\u0939\u094b\u0902 \u092e\u0947\u0902 \u092b\u0948\u0932 \u0917\u092f\u093e\u0964",creator:"\u0907\u0938\u0947 \u092c\u094d\u0930\u093f\u091f\u093f\u0936 \u0924\u0902\u0924\u094d\u0930\u093f\u0915\u093e-\u092e\u0928\u094b\u0935\u0948\u091c\u094d\u091e\u093e\u0928\u093f\u0915 Tim Shallice \u0928\u0947 1982 \u092e\u0947\u0902 \u0905\u092a\u0928\u0947 \u0936\u094b\u0927-\u092a\u0924\u094d\u0930 Specific impairments of planning (Philosophical Transactions of the Royal Society of London) \u092e\u0947\u0902 \u0930\u091a\u093e\u0964 \u092f\u0939 \u092a\u0941\u0930\u093e\u0928\u0940 Tower of Hanoi \u092a\u0939\u0947\u0932\u0940 \u0915\u093e \u090f\u0915 \u0938\u094b\u091a\u093e-\u0938\u092e\u091d\u093e \u0938\u0930\u0932\u0940\u0915\u0930\u0923 \u0939\u0948, \u091c\u093f\u0938\u0947 \u092b\u094d\u0930\u093e\u0902\u0938\u0940\u0938\u0940 \u0917\u0923\u093f\u0924\u091c\u094d\u091e Edouard Lucas \u0928\u0947 1883 \u092e\u0947\u0902 \u092a\u094d\u0930\u0915\u093e\u0936\u093f\u0924 \u0915\u093f\u092f\u093e \u0925\u093e\u0964",methods:"\u0905\u092a\u0928\u0940 \u092a\u0939\u0932\u0940 \u091a\u093e\u0932 \u0938\u0947 \u092a\u0939\u0932\u0947 \u092a\u0942\u0930\u0947 \u0915\u094d\u0930\u092e \u0915\u0940 \u092f\u094b\u091c\u0928\u093e \u092c\u0928\u093e \u0932\u0947\u0902, \u092c\u091c\u093e\u092f \u0907\u0938\u0915\u0947 \u0915\u093f \u0917\u0947\u0902\u0926\u0947\u0902 \u0907\u0927\u0930-\u0909\u0927\u0930 \u0916\u093f\u0938\u0915\u093e\u0924\u0947 \u0930\u0939\u0947\u0902 \u0914\u0930 \u0909\u092e\u094d\u092e\u0940\u0926 \u0915\u0930\u0924\u0947 \u0930\u0939\u0947\u0902\u0964 \u0932\u0915\u094d\u0937\u094d\u092f \u0938\u0947 \u0909\u0932\u094d\u091f\u093e \u0915\u093e\u092e \u0915\u0930\u0947\u0902, \u092a\u0942\u091b\u0947\u0902 \u0915\u093f \u0939\u0930 \u0916\u0942\u0901\u091f\u0940 \u0915\u0947 \u0938\u092c\u0938\u0947 \u0928\u0940\u091a\u0947 \u0915\u094c\u0928-\u0938\u0940 \u0917\u0947\u0902\u0926 \u0906\u0928\u0940 \u091a\u093e\u0939\u093f\u090f, \u0914\u0930 \u0910\u0938\u0940 \u091a\u093e\u0932\u094b\u0902 \u092a\u0930 \u0928\u091c\u093c\u0930 \u0930\u0916\u0947\u0902 \u091c\u094b \u0906\u092a\u0915\u094b \u0915\u0941\u091b \u0926\u0947\u0930 \u0915\u0947 \u0932\u093f\u090f \u0932\u0915\u094d\u0937\u094d\u092f \u0938\u0947 \u0914\u0930 \u0926\u0942\u0930 \u0932\u0947 \u091c\u093e\u0924\u0940 \u0939\u0948\u0902 \u092a\u0930 \u091f\u093e\u0932\u0940 \u0928\u0939\u0940\u0902 \u091c\u093e \u0938\u0915\u0924\u0940\u0902\u0964 \u0939\u0930 \u092a\u0939\u0947\u0932\u0940 \u0915\u0947 \u0932\u093f\u090f \u0928\u094d\u092f\u0942\u0928\u0924\u092e-\u091a\u093e\u0932 \u0938\u0902\u0916\u094d\u092f\u093e \u092a\u0930 \u0928\u091c\u093c\u0930 \u0930\u0916\u0928\u093e \u0906\u092a\u0915\u094b \u0908\u092e\u093e\u0928\u0926\u093e\u0930 \u092c\u0928\u093e\u090f \u0930\u0916\u0924\u093e \u0939\u0948\u0964",duration:"\u091b\u094b\u091f\u0947, \u090f\u0915\u093e\u0917\u094d\u0930 \u0938\u0947\u091f \u0938\u092c\u0938\u0947 \u0905\u091a\u094d\u091b\u0947 \u0930\u0939\u0924\u0947 \u0939\u0948\u0902: \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u0915\u0941\u091b \u092c\u093e\u0930, \u0939\u0930 \u092c\u093e\u0930 \u092a\u093e\u0901\u091a \u0938\u0947 \u0926\u0938 \u092e\u093f\u0928\u091f, \u092c\u0922\u093c\u0924\u0940 \u0915\u0920\u093f\u0928\u093e\u0908 \u0915\u0940 \u0915\u0941\u091b \u092a\u0939\u0947\u0932\u093f\u092f\u093e\u0901\u0964 \u092f\u0939 \u0926\u093f\u092e\u093e\u0917\u093c \u092a\u0930 \u092c\u094b\u091d \u0921\u093e\u0932\u0928\u0947 \u0935\u093e\u0932\u093e \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u092f\u094b\u091c\u0928\u093e \u0915\u0940 \u0917\u0941\u0923\u0935\u0924\u094d\u0924\u093e \u092e\u093e\u0924\u094d\u0930\u093e \u0938\u0947 \u0915\u0939\u0940\u0902 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u092e\u093e\u092f\u0928\u0947 \u0930\u0916\u0924\u0940 \u0939\u0948, \u0914\u0930 \u0907\u0938\u0947 \u0918\u0902\u091f\u0947 \u092d\u0930 \u0930\u0917\u0921\u093c\u0928\u0947 \u0915\u093e \u0915\u094b\u0908 \u0916\u093c\u093e\u0938 \u092e\u0924\u0932\u092c \u0928\u0939\u0940\u0902\u0964",research:"\u091c\u094b \u092c\u093e\u0924 \u0920\u094b\u0938 \u0930\u0942\u092a \u0938\u0947 \u0926\u093f\u0916\u093e\u0908 \u0917\u0908 \u0939\u0948 \u0935\u0939 \u0938\u0902\u0915\u0940\u0930\u094d\u0923 \u0939\u0948: \u0932\u094b\u0917 \u0916\u093c\u0941\u0926 Tower of London \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u092f\u0939 \u0915\u093e\u092e \u092f\u094b\u091c\u0928\u093e \u092c\u0928\u093e\u0928\u0947 \u0915\u093e \u090f\u0915 \u0938\u091a\u092e\u0941\u091a \u0938\u0902\u0935\u0947\u0926\u0928\u0936\u0940\u0932 \u0928\u0948\u0926\u093e\u0928\u093f\u0915 \u092e\u093e\u092a \u0939\u0948 \u091c\u094b \u092a\u094d\u0930\u0940\u092b\u094d\u0930\u0902\u091f\u0932 \u0915\u094d\u0937\u0924\u093f \u0915\u0947 \u092c\u093e\u0926 \u0914\u0930 \u0915\u0908 \u0938\u094d\u0925\u093f\u0924\u093f\u092f\u094b\u0902 \u092e\u0947\u0902 \u092c\u093f\u0917\u0921\u093c \u091c\u093e\u0924\u093e \u0939\u0948\u0964 \u0907\u0938\u0915\u0947 \u0905\u092d\u094d\u092f\u093e\u0938 \u0938\u0947 \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0940 \u092f\u094b\u091c\u0928\u093e \u0935\u094d\u092f\u093e\u092a\u0915 \u0930\u0942\u092a \u0938\u0947 \u0924\u0947\u091c\u093c \u0939\u094b\u0928\u0947, \u092c\u0941\u0926\u094d\u0927\u093f \u092c\u0922\u093c\u0928\u0947 \u092f\u093e \u0938\u0902\u091c\u094d\u091e\u093e\u0928\u093e\u0924\u094d\u092e\u0915 \u0917\u093f\u0930\u093e\u0935\u091f \u0938\u0947 \u092c\u091a\u093e\u0935 \u0939\u094b\u0928\u0947 \u0924\u0915 \u0915\u0940 \u0932\u094b\u0915\u092a\u094d\u0930\u093f\u092f \u091b\u0932\u093e\u0901\u0917 \u0915\u092e\u091c\u093c\u094b\u0930 \u0914\u0930 \u092c\u0921\u093c\u0947 \u092a\u0948\u092e\u093e\u0928\u0947 \u092a\u0930 \u0905\u092a\u094d\u0930\u092e\u093e\u0923\u093f\u0924 \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0926\u0942\u0930\u0917\u093e\u092e\u0940 \u0939\u0938\u094d\u0924\u093e\u0902\u0924\u0930\u0923 \u0915\u0947 \u0926\u093e\u0935\u094b\u0902 \u0915\u094b \u0938\u093e\u0935\u0927\u093e\u0928\u0940 \u0938\u0947 \u0932\u0947\u0902\u0964",rec:"\u0930\u0941\u0915\u0947\u0902 \u0914\u0930 \u092a\u0939\u0932\u0940 \u091a\u093e\u0932 \u0938\u0947 \u092a\u0939\u0932\u0947 \u092a\u0942\u0930\u093e \u0930\u093e\u0938\u094d\u0924\u093e \u0905\u092a\u0928\u0947 \u0926\u093f\u092e\u093e\u0917 \u092e\u0947\u0902 \u092c\u0928\u093e \u0932\u0947\u0902, \u092b\u093f\u0930 \u092c\u093f\u0928\u093e \u0926\u094b\u092c\u093e\u0930\u093e \u0938\u094b\u091a\u0947 \u0909\u0938\u0947 \u0905\u0902\u091c\u093e\u092e \u0926\u0947\u0902, \u0914\u0930 \u0909\u0938\u0915\u0947 \u092c\u093e\u0926 \u0939\u0940 \u091c\u093e\u0901\u091a\u0947\u0902 \u0915\u093f \u0906\u092a \u0928\u094d\u092f\u0942\u0928\u0924\u092e \u0915\u0947 \u0915\u093f\u0924\u0928\u0947 \u0915\u0930\u0940\u092c \u092a\u0939\u0941\u0901\u091a\u0947\u0964",faq:[["\u0915\u094d\u092f\u093e Tower of London \u0914\u0930 Tower of Hanoi \u090f\u0915 \u0939\u0940 \u0939\u0948\u0902?","\u0928\u0939\u0940\u0902\u0964 Tower of Hanoi \u0905\u0932\u0917-\u0905\u0932\u0917 \u092e\u093e\u092a \u0915\u0940 \u091a\u0915\u0924\u093f\u092f\u093e\u0901 \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0915\u0930\u0924\u093e \u0939\u0948 \u091c\u093f\u0928\u094d\u0939\u0947\u0902 \u0939\u092e\u0947\u0936\u093e \u092e\u093e\u092a-\u0915\u094d\u0930\u092e \u092e\u0947\u0902 \u0930\u0939\u0928\u093e \u0939\u094b\u0924\u093e \u0939\u0948, \u091c\u092c\u0915\u093f Tower of London \u090f\u0915 \u0939\u0940 \u092e\u093e\u092a \u0915\u0940 \u0917\u0947\u0902\u0926\u0947\u0902 \u0914\u0930 \u0910\u0938\u0940 \u0916\u0942\u0901\u091f\u093f\u092f\u093e\u0901 \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0915\u0930\u0924\u093e \u0939\u0948 \u091c\u093f\u0928 \u092a\u0930 \u0915\u0947\u0935\u0932 \u090f\u0915, \u0926\u094b \u092f\u093e \u0924\u0940\u0928 \u0917\u0947\u0902\u0926\u0947\u0902 \u0906\u0924\u0940 \u0939\u0948\u0902\u0964 \u0935\u0947 \u090f\u0915 \u091c\u0948\u0938\u0947 \u0926\u093f\u0916\u0924\u0947 \u0939\u0948\u0902 \u092a\u0930 \u092f\u094b\u091c\u0928\u093e-\u0936\u0915\u094d\u0924\u093f \u092a\u0930 \u0925\u094b\u0921\u093c\u0947 \u0905\u0932\u0917 \u0922\u0902\u0917 \u0938\u0947 \u091c\u093c\u094b\u0930 \u0921\u093e\u0932\u0924\u0947 \u0939\u0948\u0902\u0964"],["\u0915\u094d\u092f\u093e \u0907\u0938\u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u092e\u0941\u091d\u0947 \u0905\u0938\u0932 \u091c\u093c\u093f\u0902\u0926\u0917\u0940 \u092e\u0947\u0902 \u092f\u094b\u091c\u0928\u093e \u092c\u0928\u093e\u0928\u0947 \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u092c\u0928\u093e \u0926\u0947\u0917\u093e?","\u092f\u0939 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0922\u0902\u0917 \u0938\u0947 \u0906\u092a\u0915\u094b \u092a\u0939\u0947\u0932\u0940 \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u092c\u0928\u093e\u0924\u093e \u0939\u0948, \u0914\u0930 \u092f\u0939 \u092f\u094b\u091c\u0928\u093e \u092c\u0928\u093e\u0928\u0947 \u0915\u093e \u090f\u0915 \u0938\u092e\u094d\u092e\u093e\u0928\u093f\u0924 \u0928\u0948\u0926\u093e\u0928\u093f\u0915 \u092a\u0930\u0940\u0915\u094d\u0937\u0923 \u0939\u0948\u0964 \u092a\u0930 \u0905\u092a\u0928\u0947 \u0926\u093f\u0928 \u092f\u093e \u092a\u0930\u093f\u092f\u094b\u091c\u0928\u093e\u0913\u0902 \u0915\u094b \u0935\u094d\u092f\u0935\u0938\u094d\u0925\u093f\u0924 \u0915\u0930\u0928\u0947 \u0924\u0915 \u092e\u091c\u093c\u092c\u0942\u0924 \u0939\u0938\u094d\u0924\u093e\u0902\u0924\u0930\u0923 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0922\u0902\u0917 \u0938\u0947 \u0938\u093f\u0926\u094d\u0927 \u0928\u0939\u0940\u0902 \u0939\u0941\u0906 \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0907\u0938\u0947 \u091c\u0940\u0935\u0928 \u092e\u0947\u0902 \u0915\u093f\u0938\u0940 \u092a\u0915\u094d\u0915\u0940 \u0909\u0928\u094d\u0928\u0924\u093f \u0915\u0947 \u092c\u091c\u093e\u092f \u090f\u0915\u093e\u0917\u094d\u0930 \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u0906\u0928\u0902\u0926 \u0932\u0947\u0902\u0964"],["\u0905\u091a\u094d\u091b\u0947 \u0928\u0924\u0940\u091c\u0947 \u0915\u0947 \u0924\u094c\u0930 \u092a\u0930 \u0915\u094d\u092f\u093e \u0917\u093f\u0928\u093e \u091c\u093e\u0924\u093e \u0939\u0948?","\u0939\u0930 \u092c\u094b\u0930\u094d\u0921 \u0915\u094b \u0928\u094d\u092f\u0942\u0928\u0924\u092e \u091a\u093e\u0932\u094b\u0902 \u092e\u0947\u0902 \u0939\u0932 \u0915\u0930\u0928\u093e, \u0906\u0926\u0930\u094d\u0936 \u0930\u0942\u092a \u0938\u0947 \u0915\u094d\u0930\u092e \u0915\u094b \u0906\u091c\u093c\u092e\u093e\u0907\u0936-\u0914\u0930-\u092d\u0942\u0932 \u0915\u0947 \u092c\u091c\u093e\u092f \u0905\u092a\u0928\u0947 \u0926\u093f\u092e\u093e\u0917 \u092e\u0947\u0902 \u092f\u094b\u091c\u0928\u093e \u092c\u0928\u093e\u0915\u0930\u0964 \u092a\u0939\u0932\u0940 \u091a\u093e\u0932 \u0938\u0947 \u092a\u0939\u0932\u0947 \u0915\u0941\u091b \u0938\u0947\u0915\u0902\u0921 \u0938\u094b\u091a\u0928\u093e \u0914\u0930 \u092b\u093f\u0930 \u0915\u092e \u0938\u0941\u0927\u093e\u0930\u094b\u0902 \u0915\u0940 \u091c\u093c\u0930\u0942\u0930\u0924 \u092a\u0921\u093c\u0928\u093e, \u0924\u0947\u091c\u093c \u0914\u0930 \u0939\u0921\u093c\u092c\u0921\u093c\u0940 \u092d\u0930\u0940 \u0909\u0920\u093e-\u092a\u091f\u0915 \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u0938\u0902\u0915\u0947\u0924 \u0939\u0948\u0964"]],variants:"\u0928\u093f\u0915\u091f \u0915\u0947 \u0930\u093f\u0936\u094d\u0924\u0947\u0926\u093e\u0930\u094b\u0902 \u092e\u0947\u0902 Tower of Hanoi (\u0915\u094d\u0937\u092e\u0924\u093e-\u0938\u0940\u092e\u093f\u0924 \u0916\u0942\u0901\u091f\u093f\u092f\u094b\u0902 \u0915\u0947 \u092c\u091c\u093e\u092f \u092e\u093e\u092a-\u0915\u094d\u0930\u092e \u0935\u093e\u0932\u0940 \u091a\u0915\u0924\u093f\u092f\u093e\u0901), CANTAB \u0938\u092e\u0942\u0939 \u0915\u0940 Stockings of Cambridge, Drexel Tower of London (ToL-DX), D-KEFS \u092e\u0947\u0902 Tower Test, \u0914\u0930 Freiburg TOL-F \u0936\u093e\u092e\u093f\u0932 \u0939\u0948\u0902\u0964 \u0930\u0942\u092a \u0917\u0947\u0902\u0926\u094b\u0902 \u092f\u093e \u091a\u0915\u0924\u093f\u092f\u094b\u0902 \u0915\u0940 \u0938\u0902\u0916\u094d\u092f\u093e, \u0916\u0942\u0901\u091f\u093f\u092f\u094b\u0902 \u0915\u0940 \u092c\u0928\u093e\u0935\u091f, \u0914\u0930 \u0907\u0938 \u092c\u093e\u0924 \u092e\u0947\u0902 \u092b\u093c\u0930\u094d\u0915 \u0930\u0916\u0924\u0947 \u0939\u0948\u0902 \u0915\u093f \u092f\u094b\u091c\u0928\u093e-\u0938\u092e\u092f \u0915\u094b \u0928\u093f\u0937\u094d\u092a\u093e\u0926\u0928-\u0938\u092e\u092f \u0938\u0947 \u0915\u093f\u0924\u0928\u0940 \u0938\u0916\u093c\u094d\u0924\u0940 \u0938\u0947 \u0905\u0932\u0917 \u0915\u093f\u092f\u093e \u091c\u093e\u0924\u093e \u0939\u0948\u0964"},zh:{about:"\u300c\u4f26\u6566\u5854\u300d\u662f\u4e00\u6b3e\u89c4\u5212\u7c7b\u8c1c\u9898\uff0c\u4e09\u9897\u5f69\u8272\u5c0f\u7403\u6446\u5728\u4e09\u6839\u5bb9\u91cf\u5404\u4e0d\u76f8\u540c\uff08\u5206\u522b\u80fd\u653e\u4e00\u9897\u3001\u4e24\u9897\u548c\u4e09\u9897\uff09\u7684\u67f1\u5b50\u4e0a\u3002\u4f60\u4f1a\u770b\u5230\u4e00\u4e2a\u76ee\u6807\u6446\u6cd5\uff0c\u8981\u5728\u5c3d\u53ef\u80fd\u5c11\u7684\u6b65\u6570\u5185\u79fb\u52a8\u8fd9\u4e9b\u7403\uff0c\u6bcf\u6b21\u53ea\u80fd\u79fb\u52a8\u4e00\u9897\u3001\u800c\u4e14\u53ea\u80fd\u79fb\u52a8\u67d0\u6839\u67f1\u5b50\u6700\u4e0a\u9762\u7684\u90a3\u9897\uff0c\u76f4\u5230\u4f60\u7684\u68cb\u76d8\u4e0e\u76ee\u6807\u4e00\u81f4\u3002",benefit:"\u5b83\u953b\u70bc\u7684\u662f\u89c4\u5212\u4e0e\u524d\u77bb\uff1a\u5728\u8111\u4e2d\u8bb0\u4f4f\u76ee\u6807\uff0c\u5728\u52a8\u624b\u4e4b\u524d\u5148\u5728\u5fc3\u91cc\u6a21\u62df\u4e00\u8fde\u4e32\u8d70\u6cd5\uff0c\u5e76\u5728\u90a3\u4e2a\u663e\u800c\u6613\u89c1\u7684\u7b2c\u4e00\u6b65\u4f1a\u901a\u5411\u6b7b\u8def\u65f6\u6309\u4f4f\u4e0d\u8d70\u3002\u5de5\u4f5c\u8bb0\u5fc6\u548c\u51b2\u52a8\u63a7\u5236\u4e5f\u4f1a\u987a\u5e26\u5f97\u5230\u953b\u70bc\u3002",history:"\u5b83\u8131\u80ce\u4e8e\u4e34\u5e8a\u795e\u7ecf\u5fc3\u7406\u5b66\uff0c\u800c\u975e\u6e38\u620f\u3002\u8482\u59c6\xb7\u6c99\u5229\u65af\uff08Tim Shallice\uff09\u57281982\u5e74\u5f15\u5165\u5b83\uff0c\u7528\u6765\u6d4b\u91cf\u989d\u53f6\u53d7\u635f\u60a3\u8005\u7684\u89c4\u5212\u7f3a\u9677\uff1b\u5b83\u5f88\u5feb\u88ab\u5404\u7c7b\u6d4b\u9a8c\u5957\u7ec4\u91c7\u7528\uff0c\u6210\u4e86\u524d\u989d\u53f6\u76ae\u5c42\u8111\u6210\u50cf\u7814\u7a76\u4e2d\u7684\u5e38\u5907\u5de5\u5177\uff0c\u5e76\u6269\u6563\u8fdb\u4e86\u5404\u7c7b\u5e94\u7528\u548c\u5927\u8111\u8bad\u7ec3\u5408\u96c6\u4e2d\u3002",creator:"\u7531\u82f1\u56fd\u795e\u7ecf\u5fc3\u7406\u5b66\u5bb6\u8482\u59c6\xb7\u6c99\u5229\u65af\uff08Tim Shallice\uff09\u4e8e1982\u5e74\u5728\u5176\u8bba\u6587\u300a\u89c4\u5212\u7684\u7279\u5b9a\u635f\u4f24\u300b\uff08Specific impairments of planning\uff0c\u8f7d\u4e8e\u300a\u4f26\u6566\u7687\u5bb6\u5b66\u4f1a\u54f2\u5b66\u6c47\u520a\u300b\uff09\u4e2d\u521b\u7acb\u3002\u5b83\u662f\u5bf9\u66f4\u53e4\u8001\u7684\u300c\u6c49\u8bfa\u5854\u300d\u8c1c\u9898\u7684\u523b\u610f\u7b80\u5316\uff0c\u540e\u8005\u7531\u6cd5\u56fd\u6570\u5b66\u5bb6\u7231\u5fb7\u534e\xb7\u5362\u5361\u65af\uff08Edouard Lucas\uff09\u4e8e1883\u5e74\u53d1\u8868\u3002",methods:"\u5728\u8d70\u7b2c\u4e00\u6b65\u4e4b\u524d\u5c31\u628a\u6574\u5957\u8d70\u6cd5\u89c4\u5212\u597d\uff0c\u800c\u4e0d\u662f\u4e00\u8fb9\u63a8\u7403\u4e00\u8fb9\u78b0\u8fd0\u6c14\u3002\u4ece\u76ee\u6807\u5012\u63a8\uff0c\u5148\u95ee\u6bcf\u6839\u67f1\u5b50\u7684\u6700\u5e95\u5c42\u6700\u7ec8\u8be5\u662f\u54ea\u9897\u7403\uff0c\u5e76\u7559\u610f\u90a3\u4e9b\u4f1a\u6682\u65f6\u8ba9\u4f60\u79bb\u76ee\u6807\u66f4\u8fdc\u3001\u4f46\u53c8\u65e0\u6cd5\u56de\u907f\u7684\u8d70\u6cd5\u3002\u4e3a\u6bcf\u9053\u9898\u8bb0\u5f55\u6700\u5c11\u6b65\u6570\uff0c\u80fd\u8ba9\u4f60\u4e0d\u81f3\u4e8e\u81ea\u6b3a\u3002",duration:"\u77ed\u800c\u4e13\u6ce8\u7684\u9898\u7ec4\u6548\u679c\u6700\u597d\uff1a\u6bcf\u6b21\u4e94\u5230\u5341\u5206\u949f\uff0c\u505a\u51e0\u9053\u96be\u5ea6\u9012\u589e\u7684\u9898\uff0c\u6bcf\u5468\u7ec3\u51e0\u6b21\u3002\u5b83\u5f88\u8d39\u8111\uff0c\u6240\u4ee5\u89c4\u5212\u7684\u8d28\u91cf\u8fdc\u6bd4\u6570\u91cf\u91cd\u8981\uff0c\u78d5\u4e0a\u4e00\u4e2a\u5c0f\u65f6\u51e0\u4e4e\u6ca1\u6709\u610f\u4e49\u3002",research:"\u5f97\u5230\u624e\u5b9e\u8bc1\u660e\u7684\u7ed3\u8bba\u662f\u72ed\u7a84\u7684\uff1a\u4eba\u4eec\u4f1a\u66f4\u64c5\u957f\u4f26\u6566\u5854\u672c\u8eab\uff0c\u800c\u4e14\u8fd9\u9879\u4efb\u52a1\u786e\u5b9e\u662f\u4e00\u79cd\u5bf9\u89c4\u5212\u7075\u654f\u7684\u4e34\u5e8a\u6d4b\u91cf\u624b\u6bb5\u2014\u2014\u524d\u989d\u53f6\u53d7\u635f\u4ee5\u53ca\u82e5\u5e72\u79cd\u75c5\u75c7\u4e4b\u540e\uff0c\u8fd9\u79cd\u80fd\u529b\u90fd\u4f1a\u53d7\u635f\u3002\u4f46\u4ece\u300c\u7ec3\u5b83\u300d\u4e00\u8dc3\u5230\u300c\u65e5\u5e38\u89c4\u5212\u666e\u904d\u53d8\u654f\u9510\u3001\u667a\u529b\u66f4\u9ad8\u3001\u6216\u80fd\u9632\u6b62\u8ba4\u77e5\u8870\u9000\u300d\uff0c\u8fd9\u79cd\u63a8\u8bba\u662f\u8584\u5f31\u7684\uff0c\u4e5f\u57fa\u672c\u672a\u83b7\u8bc1\u5b9e\uff0c\u6240\u4ee5\u5bf9\u90a3\u4e9b\u5f71\u54cd\u6df1\u8fdc\u7684\u8fc1\u79fb\u8bf4\u6cd5\u8981\u4fdd\u6301\u8c28\u614e\u3002",rec:"\u505c\u4e00\u505c\uff0c\u5728\u8111\u4e2d\u628a\u6574\u6761\u8def\u7ebf\u89c4\u5212\u597d\uff0c\u518d\u8d70\u7b2c\u4e00\u6b65\uff0c\u7136\u540e\u7167\u7740\u6267\u884c\u3001\u4e0d\u8981\u4e2d\u9014\u53cd\u6094\uff0c\u7b49\u505a\u5b8c\u4e86\u518d\u53bb\u770b\u4f60\u79bb\u6700\u5c11\u6b65\u6570\u5dee\u4e86\u591a\u5c11\u3002",faq:[["\u4f26\u6566\u5854\u548c\u6c49\u8bfa\u5854\u662f\u4e00\u56de\u4e8b\u5417\uff1f","\u4e0d\u662f\u3002\u6c49\u8bfa\u5854\u7528\u7684\u662f\u5927\u5c0f\u4e0d\u540c\u3001\u4e14\u5fc5\u987b\u59cb\u7ec8\u4fdd\u6301\u4ece\u5927\u5230\u5c0f\u987a\u5e8f\u7684\u5706\u76d8\uff0c\u800c\u4f26\u6566\u5854\u7528\u7684\u662f\u5927\u5c0f\u76f8\u540c\u7684\u7403\uff0c\u4ee5\u53ca\u53ea\u80fd\u653e\u4e00\u9897\u3001\u4e24\u9897\u6216\u4e09\u9897\u7403\u7684\u67f1\u5b50\u3002\u5b83\u4eec\u770b\u7740\u76f8\u4f3c\uff0c\u4f46\u5bf9\u89c4\u5212\u7684\u8003\u9a8c\u65b9\u5f0f\u7565\u6709\u4e0d\u540c\u3002"],["\u7ec3\u8fd9\u4e2a\u4f1a\u8ba9\u6211\u5728\u73b0\u5b9e\u751f\u6d3b\u4e2d\u66f4\u64c5\u957f\u505a\u89c4\u5212\u5417\uff1f","\u5b83\u4f1a\u53ef\u9760\u5730\u8ba9\u4f60\u66f4\u64c5\u957f\u8fd9\u9053\u8c1c\u9898\uff0c\u800c\u4e14\u5b83\u4e5f\u662f\u4e00\u9879\u53d7\u4eba\u8ba4\u53ef\u7684\u4e34\u5e8a\u89c4\u5212\u6d4b\u9a8c\u3002\u4f46\u8981\u8bf4\u5b83\u80fd\u5f3a\u529b\u8fc1\u79fb\u5230\u5b89\u6392\u4f60\u7684\u65e5\u7a0b\u6216\u9879\u76ee\u4e0a\uff0c\u76ee\u524d\u8fd8\u6ca1\u6709\u4ee4\u4eba\u4fe1\u670d\u7684\u8bc1\u660e\uff0c\u6240\u4ee5\u8bf7\u628a\u5b83\u5f53\u4f5c\u4e00\u79cd\u4e13\u6ce8\u7684\u7ec3\u4e60\u6765\u4eab\u53d7\uff0c\u800c\u975e\u4e00\u6b21\u6709\u4fdd\u969c\u7684\u4eba\u751f\u5347\u7ea7\u3002"],["\u4ec0\u4e48\u6837\u624d\u7b97\u4e00\u4e2a\u597d\u6210\u7ee9\uff1f","\u7528\u6700\u5c11\u7684\u6b65\u6570\u89e3\u51fa\u6bcf\u4e00\u4e2a\u68cb\u76d8\uff0c\u800c\u4e14\u6700\u597d\u662f\u5728\u8111\u4e2d\u89c4\u5212\u597d\u8d70\u6cd5\u4e4b\u540e\uff0c\u800c\u4e0d\u662f\u9760\u8bd5\u9519\u3002\u5728\u8d70\u7b2c\u4e00\u6b65\u4e4b\u524d\u82b1\u51e0\u79d2\u949f\u601d\u8003\uff0c\u7136\u540e\u51e0\u4e4e\u4e0d\u9700\u8981\u4fee\u6b63\u2014\u2014\u8fd9\u6bd4\u624b\u5fd9\u811a\u4e71\u5730\u5feb\u901f\u4e71\u63a8\u8981\u66f4\u8bf4\u660e\u95ee\u9898\u3002"]],variants:"\u4e0e\u5b83\u76f8\u8fd1\u7684\u6709\uff1a\u6c49\u8bfa\u5854\uff08\u7528\u6309\u5927\u5c0f\u6392\u5e8f\u7684\u5706\u76d8\uff0c\u800c\u975e\u5bb9\u91cf\u53d7\u9650\u7684\u67f1\u5b50\uff09\u3001CANTAB \u6d4b\u9a8c\u5957\u7ec4\u4e2d\u7684\u300c\u5251\u6865\u957f\u889c\u300d\uff08Stockings of Cambridge\uff09\u3001\u5fb7\u96f7\u585e\u5c14\u7248\u4f26\u6566\u5854\uff08ToL-DX\uff09\u3001D-KEFS \u4e2d\u7684\u5854\u6d4b\u9a8c\uff08Tower Test\uff09\uff0c\u4ee5\u53ca\u5f17\u83b1\u5821\u7248 TOL-F\u3002\u5404\u7248\u672c\u5728\u7403\u6216\u5706\u76d8\u7684\u6570\u91cf\u3001\u67f1\u5b50\u7684\u5e03\u5c40\uff0c\u4ee5\u53ca\u5bf9\u300c\u89c4\u5212\u65f6\u95f4\u300d\u4e0e\u300c\u6267\u884c\u65f6\u95f4\u300d\u5206\u79bb\u5f97\u6709\u591a\u4e25\u683c\u4e0a\u5404\u6709\u4e0d\u540c\u3002"}},"trail-making":{ru:{about:"Trail Making \u2014 \u044d\u0442\u043e \u0437\u0430\u0434\u0430\u0447\u0430 \u043d\u0430 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u043f\u043e \u043f\u0440\u0438\u043d\u0446\u0438\u043f\u0443 \xab\u0441\u043e\u0435\u0434\u0438\u043d\u0438 \u0442\u043e\u0447\u043a\u0438\xbb. \u041d\u0430 \u044d\u043a\u0440\u0430\u043d\u0435 \u0440\u0430\u0437\u0431\u0440\u043e\u0441\u0430\u043d\u044b \u043a\u0440\u0443\u0436\u043a\u0438, \u0438 \u043d\u0443\u0436\u043d\u043e \u043a\u0430\u043a \u043c\u043e\u0436\u043d\u043e \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u043d\u0430\u0436\u0438\u043c\u0430\u0442\u044c \u0438\u0445 \u043f\u043e \u043f\u043e\u0440\u044f\u0434\u043a\u0443, \u043d\u0435 \u0442\u0435\u0440\u044f\u044f \u0442\u0435\u043c\u043f\u0430: \u0432 \u043f\u0440\u043e\u0441\u0442\u043e\u043c \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u0435 \u044d\u0442\u043e \u0447\u0438\u0441\u043b\u0430 1-2-3 \u0438 \u0442\u0430\u043a \u0434\u043e \u043f\u043e\u0441\u043b\u0435\u0434\u043d\u0435\u0433\u043e, \u0430 \u0432 \u0441\u043b\u043e\u0436\u043d\u043e\u043c \u0432\u044b \u0447\u0435\u0440\u0435\u0434\u0443\u0435\u0442\u0435 \u0447\u0438\u0441\u043b\u0430 \u0438 \u0431\u0443\u043a\u0432\u044b, 1-\u0410-2-\u0411-3-\u0412, \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0430\u044f\u0441\u044c \u043d\u0430 \u043a\u0430\u0436\u0434\u043e\u043c \u0448\u0430\u0433\u0435.",benefit:"\u0412 \u0447\u0438\u0441\u043b\u043e\u0432\u043e\u043c \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u0435 \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442\u0441\u044f \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0439 \u043f\u043e\u0438\u0441\u043a \u0438 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u043e\u0431\u0440\u0430\u0431\u043e\u0442\u043a\u0438 \u0438\u043d\u0444\u043e\u0440\u043c\u0430\u0446\u0438\u0438, \u0430 \u0432 \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u0435 \xab\u0447\u0438\u0441\u043b\u043e-\u0431\u0443\u043a\u0432\u0430\xbb \u0432\u0434\u043e\u0431\u0430\u0432\u043e\u043a \u0433\u0438\u0431\u043a\u043e\u0441\u0442\u044c \u043c\u044b\u0448\u043b\u0435\u043d\u0438\u044f \u2014 \u0443\u043c\u0435\u043d\u0438\u0435 \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0430\u0442\u044c\u0441\u044f \u043c\u0435\u0436\u0434\u0443 \u0434\u0432\u0443\u043c\u044f \u043f\u0440\u0430\u0432\u0438\u043b\u0430\u043c\u0438, \u043d\u0435 \u0441\u0431\u0438\u0432\u0430\u044f\u0441\u044c. \u0418\u043c\u0435\u043d\u043d\u043e \u044d\u0442\u0430 \u043d\u0435\u043e\u0431\u0445\u043e\u0434\u0438\u043c\u043e\u0441\u0442\u044c \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0430\u0442\u044c\u0441\u044f \u0434\u0435\u043b\u0430\u0435\u0442 \u0440\u0435\u0436\u0438\u043c \u0441 \u0447\u0435\u0440\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u0435\u043c \u043a\u043b\u0430\u0441\u0441\u0438\u0447\u0435\u0441\u043a\u0438\u043c \u0438\u043d\u0441\u0442\u0440\u0443\u043c\u0435\u043d\u0442\u043e\u043c \u0434\u043b\u044f \u043e\u0446\u0435\u043d\u043a\u0438 \u0443\u043f\u0440\u0430\u0432\u043b\u044f\u044e\u0449\u0438\u0445 \u0444\u0443\u043d\u043a\u0446\u0438\u0439.",history:"\u041a\u043e\u0440\u043d\u0438 \u0443\u0445\u043e\u0434\u044f\u0442 \u043a \xab\u0442\u0435\u0441\u0442\u0443 \u043f\u0443\u0442\u0435\u0439 \u041f\u0430\u0440\u0442\u0438\u043d\u0433\u0442\u043e\u043d\u0430\xbb 1938 \u0433\u043e\u0434\u0430 \u2014 \u043f\u0440\u043e\u0441\u0442\u043e\u043c\u0443 \u0431\u0443\u043c\u0430\u0436\u043d\u043e\u043c\u0443 \u0437\u0430\u0434\u0430\u043d\u0438\u044e. \u0412 1944 \u0433\u043e\u0434\u0443 \u0435\u0433\u043e \u0432\u043a\u043b\u044e\u0447\u0438\u043b\u0438 \u0432 \u0430\u0440\u043c\u0435\u0439\u0441\u043a\u0443\u044e \u0431\u0430\u0442\u0430\u0440\u0435\u044e \u0442\u0435\u0441\u0442\u043e\u0432 \u0421\u0428\u0410, \u0433\u0434\u0435 \u043e\u043d \u0438 \u043f\u043e\u043b\u0443\u0447\u0438\u043b \u043d\u0430\u0437\u0432\u0430\u043d\u0438\u0435 Trail Making Test, \u0430 \u0432 1950-\u0445 \u043d\u0435\u0439\u0440\u043e\u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433 \u0420\u0430\u043b\u044c\u0444 \u0420\u0435\u0439\u0442\u0430\u043d \u0432\u0437\u044f\u043b \u0435\u0433\u043e \u0434\u043b\u044f \u0432\u044b\u044f\u0432\u043b\u0435\u043d\u0438\u044f \u043f\u043e\u0441\u043b\u0435\u0434\u0441\u0442\u0432\u0438\u0439 \u0442\u0440\u0430\u0432\u043c \u043c\u043e\u0437\u0433\u0430 \u0438 \u0432\u0441\u0442\u0440\u043e\u0438\u043b \u0432 \u0431\u0430\u0442\u0430\u0440\u0435\u044e \u0425\u043e\u043b\u0441\u0442\u0435\u0434\u0430-\u0420\u0435\u0439\u0442\u0430\u043d\u0430. \u0418\u043c\u0435\u043d\u043d\u043e \u0435\u0433\u043e \u0431\u0443\u043c\u0430\u0436\u043d\u0430\u044f \u0432\u0435\u0440\u0441\u0438\u044f \u0434\u043e \u0441\u0438\u0445 \u043f\u043e\u0440 \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0435\u0442\u0441\u044f \u0432 \u043a\u043b\u0438\u043d\u0438\u043a\u0430\u0445 \u0447\u0430\u0449\u0435 \u0432\u0441\u0435\u0433\u043e.",creator:"\u0415\u0434\u0438\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0433\u043e \u0441\u043e\u0432\u0440\u0435\u043c\u0435\u043d\u043d\u043e\u0433\u043e \u0430\u0432\u0442\u043e\u0440\u0430 \u0443 \u0437\u0430\u0434\u0430\u043d\u0438\u044f \u043d\u0435\u0442. \u041f\u0435\u0440\u0432\u0443\u044e \u0432\u0435\u0440\u0441\u0438\u044e \u043f\u0440\u0438\u043f\u0438\u0441\u044b\u0432\u0430\u044e\u0442 \u0430\u043c\u0435\u0440\u0438\u043a\u0430\u043d\u0441\u043a\u043e\u043c\u0443 \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0443 \u0414\u0436\u043e\u043d\u0443 \u041f\u0430\u0440\u0442\u0438\u043d\u0433\u0442\u043e\u043d\u0443 \u043e\u043a\u043e\u043b\u043e 1938 \u0433\u043e\u0434\u0430 (\u043e\u043f\u0443\u0431\u043b\u0438\u043a\u043e\u0432\u0430\u043d\u0430 \u043a\u0430\u043a Partington & Leiter, 1949); \u0444\u043e\u0440\u043c\u0430\u0442 \xab\u0447\u0438\u0441\u043b\u043e-\u0431\u0443\u043a\u0432\u0430\xbb \u0438 \u0441\u0430\u043c\u043e \u043d\u0430\u0437\u0432\u0430\u043d\u0438\u0435 \u043f\u0440\u0438\u0448\u043b\u0438 \u0438\u0437 \u0430\u0440\u043c\u0438\u0438 \u0421\u0428\u0410 \u0432 1944 \u0433\u043e\u0434\u0443, \u0430 \u0420\u0430\u043b\u044c\u0444 \u0420\u0435\u0439\u0442\u0430\u043d \u0441\u0442\u0430\u043d\u0434\u0430\u0440\u0442\u0438\u0437\u0438\u0440\u043e\u0432\u0430\u043b \u0438 \u043f\u043e\u043f\u0443\u043b\u044f\u0440\u0438\u0437\u0438\u0440\u043e\u0432\u0430\u043b \u0442\u0435\u0441\u0442 \u043d\u0430\u0447\u0438\u043d\u0430\u044f \u0441 1950-\u0445.",methods:"\u0417\u0430\u0440\u0430\u043d\u0435\u0435 \u0432\u0435\u0434\u0438\u0442\u0435 \u0432\u0437\u0433\u043b\u044f\u0434 \u0432\u043f\u0435\u0440\u0451\u0434 \u0438 \u043d\u0430\u0445\u043e\u0434\u0438\u0442\u0435 \u0441\u0440\u0430\u0437\u0443 \u0434\u0432\u0435-\u0442\u0440\u0438 \u0441\u043b\u0435\u0434\u0443\u044e\u0449\u0438\u0435 \u0446\u0435\u043b\u0438, \u0430 \u043d\u0435 \u0432\u044b\u0438\u0441\u043a\u0438\u0432\u0430\u0439\u0442\u0435 \u043f\u043e \u043e\u0434\u043d\u043e\u0439. \u0412 \u0440\u0435\u0436\u0438\u043c\u0435 \u0441 \u0447\u0435\u0440\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u0435\u043c \u0434\u0435\u0440\u0436\u0438\u0442\u0435 \u0432 \u0433\u043e\u043b\u043e\u0432\u0435 \u0441\u0440\u0430\u0437\u0443 \u0434\u0432\u0430 \u043e\u0440\u0438\u0435\u043d\u0442\u0438\u0440\u0430 \u2014 \u0441\u043b\u0435\u0434\u0443\u044e\u0449\u0435\u0435 \u0447\u0438\u0441\u043b\u043e \u0438 \u0441\u043b\u0435\u0434\u0443\u044e\u0449\u0443\u044e \u0431\u0443\u043a\u0432\u0443, \u0442\u043e\u0433\u0434\u0430 \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0435\u043d\u0438\u0435 \u0434\u0430\u0451\u0442\u0441\u044f \u043b\u0435\u0433\u0447\u0435. \u0421\u043d\u0430\u0447\u0430\u043b\u0430 \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u044c, \u043f\u043e\u0442\u043e\u043c \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c: \u043e\u0448\u0438\u0431\u043e\u0447\u043d\u043e\u0435 \u043d\u0430\u0436\u0430\u0442\u0438\u0435 \u043e\u0431\u044b\u0447\u043d\u043e \u0441\u0442\u043e\u0438\u0442 \u0434\u043e\u0440\u043e\u0436\u0435, \u0447\u0435\u043c \u0447\u0443\u0442\u044c \u0431\u043e\u043b\u0435\u0435 \u043c\u0435\u0434\u043b\u0435\u043d\u043d\u044b\u0439, \u043d\u043e \u0432\u0435\u0440\u043d\u044b\u0439 \u0445\u043e\u0434.",duration:"\u041b\u0443\u0447\u0448\u0435 \u0432\u0441\u0435\u0433\u043e \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u0435 \u043f\u043e\u0434\u0445\u043e\u0434\u044b: \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u043f\u043e\u043b\u0435\u0439 \u0437\u0430 \u043f\u044f\u0442\u044c-\u0434\u0435\u0441\u044f\u0442\u044c \u043c\u0438\u043d\u0443\u0442, \u043f\u0430\u0440\u0443-\u0442\u0440\u043e\u0439\u043a\u0443 \u0440\u0430\u0437 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e. \u041f\u0440\u043e\u0433\u0440\u0435\u0441\u0441 \u0431\u044b\u0441\u0442\u0440\u043e \u0432\u044b\u0445\u043e\u0434\u0438\u0442 \u043d\u0430 \u043f\u043b\u0430\u0442\u043e, \u0430 \u0441\u0430\u043c\u043e \u0437\u0430\u0434\u0430\u043d\u0438\u0435 \u2014 \u044d\u0442\u043e \u0441\u043a\u043e\u0440\u0435\u0435 \u0441\u043f\u0440\u0438\u043d\u0442, \u0447\u0435\u043c \u043c\u0430\u0440\u0430\u0444\u043e\u043d, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u0447\u0430\u0441\u0442\u0430\u044f \u043a\u043e\u0440\u043e\u0442\u043a\u0430\u044f \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u0430 \u044d\u0444\u0444\u0435\u043a\u0442\u0438\u0432\u043d\u0435\u0435 \u0434\u043e\u043b\u0433\u0438\u0445 \u0438\u0437\u043c\u0430\u0442\u044b\u0432\u0430\u044e\u0449\u0438\u0445 \u0441\u0435\u0441\u0441\u0438\u0439.",research:"\u041d\u0430\u0434\u0451\u0436\u043d\u043e \u0434\u043e\u043a\u0430\u0437\u0430\u043d\u043e \u0440\u043e\u0432\u043d\u043e \u0442\u043e, \u0447\u0435\u0433\u043e \u0438 \u0441\u0442\u043e\u0438\u0442 \u043e\u0436\u0438\u0434\u0430\u0442\u044c: \u0441 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u043e\u0439 \u0432\u044b \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u0438 \u0442\u043e\u0447\u043d\u0435\u0435 \u043f\u0440\u043e\u0445\u043e\u0434\u0438\u0442\u0435 \u0438\u043c\u0435\u043d\u043d\u043e \u044d\u0442\u043e \u0437\u0430\u0434\u0430\u043d\u0438\u0435, \u0430 \u0441\u0430\u043c \u0442\u0435\u0441\u0442 \u2014 \u0445\u043e\u0440\u043e\u0448\u043e \u043f\u0440\u043e\u0432\u0435\u0440\u0435\u043d\u043d\u044b\u0439 \u043a\u043b\u0438\u043d\u0438\u0447\u0435\u0441\u043a\u0438\u0439 \u0438\u043d\u0441\u0442\u0440\u0443\u043c\u0435\u043d\u0442 \u0434\u043b\u044f \u043e\u0446\u0435\u043d\u043a\u0438 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u0438 \u043e\u0431\u0440\u0430\u0431\u043e\u0442\u043a\u0438 \u0438 \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0435\u043d\u0438\u044f. \u0410 \u0432\u043e\u0442 \u0434\u0430\u043b\u044c\u0448\u0435 \u0434\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432 \u043c\u0430\u043b\u043e. \u041a\u0440\u0443\u043f\u043d\u044b\u0435 \u043c\u0435\u0442\u0430\u0430\u043d\u0430\u043b\u0438\u0437\u044b \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043e\u043a \u043c\u043e\u0437\u0433\u0430 \u043f\u043e\u043a\u0430\u0437\u044b\u0432\u0430\u044e\u0442, \u0447\u0442\u043e \u043f\u0435\u0440\u0435\u043d\u043e\u0441 \u043d\u0430 \u043d\u0435\u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u044b\u0435 \u0441\u043f\u043e\u0441\u043e\u0431\u043d\u043e\u0441\u0442\u0438 \u0438 \u043e\u0431\u0449\u0438\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0441\u0436\u0438\u043c\u0430\u0435\u0442\u0441\u044f \u043f\u043e\u0447\u0442\u0438 \u0434\u043e \u043d\u0443\u043b\u044f, \u043a\u0430\u043a \u0442\u043e\u043b\u044c\u043a\u043e \u0432 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u044f\u0445 \u043f\u043e\u044f\u0432\u043b\u044f\u0435\u0442\u0441\u044f \u0447\u0435\u0441\u0442\u043d\u0430\u044f \u0430\u043a\u0442\u0438\u0432\u043d\u0430\u044f \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u044c\u043d\u0430\u044f \u0433\u0440\u0443\u043f\u043f\u0430. \u041f\u043e\u044d\u0442\u043e\u043c\u0443 \u043a \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f\u043c \xab\u043f\u043e\u0443\u043c\u043d\u0435\u0442\u044c \u0432 \u0446\u0435\u043b\u043e\u043c\xbb \u0438\u043b\u0438 \xab\u043e\u0442\u0441\u0440\u043e\u0447\u0438\u0442\u044c \u0441\u0442\u0430\u0440\u0435\u043d\u0438\u0435 \u043c\u043e\u0437\u0433\u0430\xbb \u0441\u0442\u043e\u0438\u0442 \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u044c\u0441\u044f \u043e\u0441\u0442\u043e\u0440\u043e\u0436\u043d\u043e.",rec:"\u0421\u0434\u0435\u043b\u0430\u0439\u0442\u0435 \u043e\u0441\u043d\u043e\u0432\u043d\u044b\u043c \u0440\u0435\u0436\u0438\u043c\u043e\u043c \u0432\u0430\u0440\u0438\u0430\u043d\u0442 \xab\u0447\u0438\u0441\u043b\u043e-\u0431\u0443\u043a\u0432\u0430\xbb: \u0438\u043c\u0435\u043d\u043d\u043e \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0435\u043d\u0438\u0435 \u043f\u0440\u0430\u0432\u0438\u043b \u0434\u0430\u0451\u0442 \u043d\u0430\u0441\u0442\u043e\u044f\u0449\u0443\u044e \u043d\u0430\u0433\u0440\u0443\u0437\u043a\u0443. \u0418 \u0434\u0435\u0440\u0436\u0438\u0442\u0435 \u043f\u043e\u0434\u0445\u043e\u0434\u044b \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u043c\u0438.",faq:[["\u0427\u0435\u043c \u0447\u0438\u0441\u043b\u043e\u0432\u043e\u0439 \u0440\u0435\u0436\u0438\u043c \u043e\u0442\u043b\u0438\u0447\u0430\u0435\u0442\u0441\u044f \u043e\u0442 \u0440\u0435\u0436\u0438\u043c\u0430 \xab\u0447\u0438\u0441\u043b\u043e-\u0431\u0443\u043a\u0432\u0430\xbb?","\u0427\u0438\u0441\u043b\u043e\u0432\u043e\u0439 \u0440\u0435\u0436\u0438\u043c \u0432 \u043e\u0441\u043d\u043e\u0432\u043d\u043e\u043c \u043f\u0440\u043e\u0432\u0435\u0440\u044f\u0435\u0442, \u043d\u0430\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0431\u044b\u0441\u0442\u0440\u043e \u0432\u044b \u0441\u043a\u0430\u043d\u0438\u0440\u0443\u0435\u0442\u0435 \u0438 \u0432\u044b\u0441\u0442\u0440\u0430\u0438\u0432\u0430\u0435\u0442\u0435 \u043f\u043e\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u044c. \u0420\u0435\u0436\u0438\u043c \xab\u0447\u0438\u0441\u043b\u043e-\u0431\u0443\u043a\u0432\u0430\xbb \u0434\u043e\u0431\u0430\u0432\u043b\u044f\u0435\u0442 \u043f\u043e\u0441\u0442\u043e\u044f\u043d\u043d\u043e\u0435 \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0435\u043d\u0438\u0435 \u043c\u0435\u0436\u0434\u0443 \u0434\u0432\u0443\u043c\u044f \u0440\u044f\u0434\u0430\u043c\u0438, \u043d\u0430\u0433\u0440\u0443\u0436\u0430\u044f \u0433\u0438\u0431\u043a\u043e\u0441\u0442\u044c \u043c\u044b\u0448\u043b\u0435\u043d\u0438\u044f, \u2014 \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u043e\u043d \u043e\u0431\u044b\u0447\u043d\u043e \u0437\u0430\u043d\u0438\u043c\u0430\u0435\u0442 \u043f\u0440\u0438\u043c\u0435\u0440\u043d\u043e \u0432\u0434\u0432\u043e\u0435 \u0431\u043e\u043b\u044c\u0448\u0435 \u0432\u0440\u0435\u043c\u0435\u043d\u0438."],["\u041a\u0430\u043a\u043e\u0435 \u0432\u0440\u0435\u043c\u044f \u0441\u0447\u0438\u0442\u0430\u0435\u0442\u0441\u044f \u0445\u043e\u0440\u043e\u0448\u0438\u043c?","\u0423 \u0437\u0434\u043e\u0440\u043e\u0432\u044b\u0445 \u0432\u0437\u0440\u043e\u0441\u043b\u044b\u0445 \u0447\u0438\u0441\u043b\u043e\u0432\u0430\u044f \u0447\u0430\u0441\u0442\u044c \u0432 \u0441\u0440\u0435\u0434\u043d\u0435\u043c \u0437\u0430\u043d\u0438\u043c\u0430\u0435\u0442 \u043e\u043a\u043e\u043b\u043e 30 \u0441\u0435\u043a\u0443\u043d\u0434, \u0430 \u0447\u0430\u0441\u0442\u044c \u0441 \u0447\u0435\u0440\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u0435\u043c \u2014 \u043e\u043a\u043e\u043b\u043e 75 \u0441\u0435\u043a\u0443\u043d\u0434, \u043d\u043e \u044d\u0442\u043e \u0441\u0438\u043b\u044c\u043d\u043e \u0437\u0430\u0432\u0438\u0441\u0438\u0442 \u043e\u0442 \u0432\u043e\u0437\u0440\u0430\u0441\u0442\u0430 \u0438 \u043a\u043e\u043d\u043a\u0440\u0435\u0442\u043d\u043e\u0439 \u0440\u0430\u0441\u043a\u043b\u0430\u0434\u043a\u0438. \u0422\u0430\u043a \u0447\u0442\u043e \u0441\u0440\u0430\u0432\u043d\u0438\u0432\u0430\u0439\u0442\u0435 \u0441\u0435\u0431\u044f \u0441\u043e \u0441\u0432\u043e\u0438\u043c\u0438 \u043f\u0440\u043e\u0448\u043b\u044b\u043c\u0438 \u043f\u043e\u043f\u044b\u0442\u043a\u0430\u043c\u0438, \u0430 \u043d\u0435 \u0441 \u0444\u0438\u043a\u0441\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u043e\u0439 \u0446\u0438\u0444\u0440\u043e\u0439."],["\u0421\u0442\u0430\u043d\u0443 \u043b\u0438 \u044f \u0443\u043c\u043d\u0435\u0435 \u0438\u043b\u0438 \u0441\u043e\u0431\u0440\u0430\u043d\u043d\u0435\u0435 \u0432 \u043e\u0431\u044b\u0447\u043d\u043e\u0439 \u0436\u0438\u0437\u043d\u0438?","\u0427\u0435\u0441\u0442\u043d\u043e \u2014 \u0432 \u0448\u0438\u0440\u043e\u043a\u043e\u043c \u0441\u043c\u044b\u0441\u043b\u0435 \u043d\u0430\u0443\u043a\u0430 \u044d\u0442\u043e\u0433\u043e \u043d\u0435 \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u0435\u0442. \u0412\u044b \u044f\u0432\u043d\u043e \u0441\u0442\u0430\u043d\u0435\u0442\u0435 \u043b\u0443\u0447\u0448\u0435 \u0432 \u044d\u0442\u043e\u043c \u0437\u0430\u0434\u0430\u043d\u0438\u0438 \u0438 \u0432 \u043f\u043e\u0445\u043e\u0436\u0435\u043c \u043f\u043e\u0438\u0441\u043a\u0435 \u0438 \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0435\u043d\u0438\u0438, \u043d\u043e \u043a\u043e\u043d\u0442\u0440\u043e\u043b\u0438\u0440\u0443\u0435\u043c\u044b\u0445 \u0434\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432 \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0430 \u043d\u0430 \u043e\u0431\u0449\u0438\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0438\u043b\u0438 \u043f\u043e\u0432\u0441\u0435\u0434\u043d\u0435\u0432\u043d\u044b\u0435 \u0434\u0435\u043b\u0430 \u043c\u0430\u043b\u043e. \u0422\u0430\u043a \u0447\u0442\u043e \u0432\u043e\u0441\u043f\u0440\u0438\u043d\u0438\u043c\u0430\u0439\u0442\u0435 \u044d\u0442\u043e \u043a\u0430\u043a \u0442\u043e\u0447\u0435\u0447\u043d\u0443\u044e \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0443, \u0430 \u043d\u0435 \u043a\u0430\u043a \u0430\u043f\u0433\u0440\u0435\u0439\u0434 \u043c\u043e\u0437\u0433\u0430."]],variants:"\u0412\u0430\u0440\u0438\u0430\u043d\u0442\u044b \u043c\u0435\u043d\u044f\u044e\u0442 \u0446\u0435\u043b\u0438 \u0438 \u043a\u0430\u043d\u0430\u043b \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0435\u043d\u0438\u044f: \u0442\u043e\u043b\u044c\u043a\u043e \u0447\u0438\u0441\u043b\u0430 (\u0447\u0430\u0441\u0442\u044c A) \u043f\u0440\u043e\u0442\u0438\u0432 \u0447\u0435\u0440\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u044f \u0447\u0438\u0441\u043b\u043e-\u0431\u0443\u043a\u0432\u0430 (\u0447\u0430\u0441\u0442\u044c B); \u0446\u0432\u0435\u0442\u043d\u044b\u0435 \u0432\u0435\u0440\u0441\u0438\u0438, \u0433\u0434\u0435 \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0430\u044e\u0442\u0441\u044f \u043c\u0435\u0436\u0434\u0443 \u0434\u0432\u0443\u043c\u044f \u0446\u0432\u0435\u0442\u0430\u043c\u0438 \u0432\u043c\u0435\u0441\u0442\u043e \u0431\u0443\u043a\u0432; \u0432\u0435\u0440\u0441\u0438\u0438 \u0441 \u0444\u0438\u0433\u0443\u0440\u0430\u043c\u0438 \u0438\u043b\u0438 \u0437\u043d\u0430\u043a\u0430\u043c\u0438 \u0437\u043e\u0434\u0438\u0430\u043a\u0430 \u0434\u043b\u044f \u0430\u043b\u0444\u0430\u0432\u0438\u0442\u043e\u0432 \u0431\u0435\u0437 \u043b\u0430\u0442\u0438\u043d\u0438\u0446\u044b; \u0443\u0441\u0442\u043d\u044b\u0435 \u0438 \xab\u0445\u043e\u0434\u044f\u0447\u0438\u0435\xbb \u0432\u0435\u0440\u0441\u0438\u0438, \u0433\u0434\u0435 \u0440\u0443\u043a\u0430 \u043d\u0435 \u0443\u0447\u0430\u0441\u0442\u0432\u0443\u0435\u0442 \u0432\u043e\u0432\u0441\u0435; \u0430 \u0442\u0430\u043a\u0436\u0435 \u0443\u0434\u043b\u0438\u043d\u0451\u043d\u043d\u044b\u0435 \u043f\u043e\u043b\u044f, \u0433\u0434\u0435 \u043f\u0440\u043e\u0441\u0442\u043e \u0434\u043e\u0431\u0430\u0432\u043b\u0435\u043d\u043e \u0431\u043e\u043b\u044c\u0448\u0435 \u043a\u0440\u0443\u0436\u043a\u043e\u0432."},en:{about:"Trail Making is a connect-the-dots speed task. The screen shows scattered circles and you tap them in the right order as fast as you can without lifting your focus: in the simple version that is numbers 1-2-3 up to the last one, and in the harder version you alternate between numbers and letters, 1-A-2-B-3-C, switching tracks on every step.",benefit:"It trains visual scanning and processing speed in the number-only version, and on top of that cognitive flexibility, the ability to switch between two rules without losing your place, in the number-letter version. That set-switching demand is what makes the alternating mode a classic window onto executive function.",history:"It grew out of Partington's Pathways Test from 1938, a simple paper task. In 1944 it was folded into the U.S. Army Individual Test Battery and got the name Trail Making Test, and in the 1950s the neuropsychologist Ralph Reitan adopted it for brain-injury screening and built it into the Halstead-Reitan battery, which made his paper-and-pencil version the one most clinics still use today.",creator:"There is no single modern inventor. The first version is credited to the American psychologist John E. Partington around 1938 (published as Partington & Leiter, 1949); the number-letter format and the name came from the U.S. Army in 1944, and Ralph Reitan standardized and popularized it from the 1950s onward.",methods:"Sweep your eyes ahead to locate the next two or three targets before you tap, rather than hunting one at a time. In the alternating mode keep two pointers in mind at once, the next number and the next letter, so the switch costs you less. Accuracy first, then speed, since a wrong tap usually costs more time than moving a touch slower.",duration:"Short sessions work best: a handful of boards over five to ten minutes, a few times a week. Because gains plateau quickly and it is more of a sprint than an endurance task, brief frequent practice beats long grinding sessions.",research:"What is solidly shown is exactly what you would expect: with practice you get faster and more accurate at trail making itself, and the task is a well-validated clinical measure of processing speed and set-switching. The leap from there to broader gains is where the evidence is weak. Large meta-analyses of cognitive training find that transfer to untrained abilities or general intelligence shrinks toward zero once studies use proper active control groups, so treat any promise that it makes you smarter overall or wards off decline with caution.",rec:"Use the number-letter mode as your main challenge, since the rule-switching is where the real workout is, and keep the runs short.",faq:[["What is the difference between the numbers-only and the number-letter mode?","The numbers-only mode mostly tests how fast you can scan and sequence. The number-letter mode adds constant rule-switching between two sequences, which loads cognitive flexibility, and that is why it normally takes people about twice as long."],["What counts as a good time?","For healthy adults the numbers-only part averages around 30 seconds and the alternating part around 75 seconds, but these depend heavily on age and the exact layout, so compare yourself to your own past runs rather than to a fixed number."],["Will this make me smarter or faster in everyday life?","Honestly, not in any broad way that research backs. You will clearly get better at this task and at similar scanning and switching, but the controlled evidence for transfer to general intelligence or daily functioning is weak, so enjoy it as focused practice, not a brain upgrade."]],variants:"Variants change the targets and the channel: number-only (Part A) versus alternating number-letter (Part B); color-based versions that switch between two colors instead of letters; shape or zodiac versions for non-Latin alphabets; oral and walking versions that drop the hand entirely; and longer grids that simply add more circles."},es:{about:"Trail Making es una tarea de velocidad del tipo \"une los puntos\". La pantalla muestra c\xedrculos dispersos y los vas tocando en el orden correcto lo m\xe1s r\xe1pido que puedes sin perder la concentraci\xf3n: en la versi\xf3n sencilla son los n\xfameros 1-2-3 hasta el \xfaltimo, y en la versi\xf3n m\xe1s dif\xedcil alternas entre n\xfameros y letras, 1-A-2-B-3-C, cambiando de v\xeda en cada paso.",benefit:"Entrena el rastreo visual y la velocidad de procesamiento en la versi\xf3n de solo n\xfameros, y adem\xe1s la flexibilidad cognitiva, la capacidad de alternar entre dos reglas sin perder el hilo, en la versi\xf3n de n\xfameros y letras. Esa exigencia de cambio de conjunto es lo que convierte al modo alterno en una ventana cl\xe1sica al funcionamiento ejecutivo.",history:"Naci\xf3 del Test de Caminos de Partington de 1938, una sencilla tarea en papel. En 1944 se incorpor\xf3 a la Army Individual Test Battery del ej\xe9rcito de EE. UU. y recibi\xf3 el nombre de Trail Making Test, y en los a\xf1os cincuenta el neuropsic\xf3logo Ralph Reitan lo adopt\xf3 para el cribado de lesiones cerebrales y lo integr\xf3 en la bater\xeda Halstead-Reitan, lo que hizo que su versi\xf3n de l\xe1piz y papel sea la que a\xfan hoy usan la mayor\xeda de las cl\xednicas.",creator:"No hay un \xfanico inventor moderno. La primera versi\xf3n se atribuye al psic\xf3logo estadounidense John E. Partington hacia 1938 (publicada como Partington y Leiter, 1949); el formato de n\xfameros y letras y el nombre vinieron del ej\xe9rcito de EE. UU. en 1944, y Ralph Reitan lo estandariz\xf3 y populariz\xf3 a partir de los a\xf1os cincuenta.",methods:"Recorre con la vista por adelantado para localizar los dos o tres objetivos siguientes antes de tocar, en lugar de buscarlos de uno en uno. En el modo alterno mant\xe9n dos punteros en mente a la vez, el siguiente n\xfamero y la siguiente letra, para que el cambio te cueste menos. Primero la precisi\xf3n y despu\xe9s la velocidad, ya que un toque equivocado suele costar m\xe1s tiempo que ir un poco m\xe1s despacio.",duration:"Las sesiones cortas funcionan mejor: un pu\xf1ado de tableros en cinco o diez minutos, unas cuantas veces por semana. Como las mejoras se estancan deprisa y es m\xe1s un esprint que una prueba de resistencia, la pr\xe1ctica breve y frecuente supera a las sesiones largas y machaconas.",research:"Lo que est\xe1 s\xf3lidamente demostrado es justo lo que cabr\xeda esperar: con la pr\xe1ctica te vuelves m\xe1s r\xe1pido y preciso en el propio trail making, y la tarea es una medida cl\xednica bien validada de la velocidad de procesamiento y del cambio de conjunto. El salto de ah\xed a beneficios m\xe1s amplios es donde la evidencia flojea. Los grandes metaan\xe1lisis del entrenamiento cognitivo encuentran que la transferencia a capacidades no entrenadas o a la inteligencia general se acerca a cero en cuanto los estudios usan grupos de control activos adecuados, as\xed que toma con cautela cualquier promesa de que te haga m\xe1s inteligente en general o que frene el deterioro.",rec:"Usa el modo de n\xfameros y letras como tu reto principal, ya que el cambio de regla es donde est\xe1 el verdadero ejercicio, y mant\xe9n las rondas cortas.",faq:[["\xbfCu\xe1l es la diferencia entre el modo de solo n\xfameros y el de n\xfameros y letras?","El modo de solo n\xfameros mide sobre todo lo r\xe1pido que puedes rastrear y secuenciar. El modo de n\xfameros y letras a\xf1ade un cambio constante de regla entre dos secuencias, lo que exige flexibilidad cognitiva, y por eso normalmente lleva a la gente alrededor del doble de tiempo."],["\xbfQu\xe9 se considera un buen tiempo?","En adultos sanos, la parte de solo n\xfameros promedia unos 30 segundos y la parte alterna unos 75 segundos, pero esto depende mucho de la edad y de la disposici\xf3n concreta, as\xed que comp\xe1rate con tus propias rondas anteriores en lugar de con una cifra fija."],["\xbfEsto me har\xe1 m\xe1s inteligente o m\xe1s r\xe1pido en la vida diaria?","Sinceramente, no de ninguna forma amplia que la investigaci\xf3n respalde. Est\xe1 claro que mejorar\xe1s en esta tarea y en rastreos y cambios parecidos, pero la evidencia controlada de transferencia a la inteligencia general o al funcionamiento diario es d\xe9bil, as\xed que disfr\xfatalo como pr\xe1ctica focalizada, no como una mejora del cerebro."]],variants:"Las variantes cambian los objetivos y el canal: solo n\xfameros (Parte A) frente a la alternancia de n\xfameros y letras (Parte B); versiones por colores que alternan entre dos colores en lugar de letras; versiones con formas o signos del zod\xedaco para alfabetos no latinos; versiones orales y caminando que prescinden por completo de la mano; y rejillas m\xe1s largas que simplemente a\xf1aden m\xe1s c\xedrculos."},de:{about:"Trail Making ist eine Punkt-zu-Punkt-Aufgabe auf Tempo. Auf dem Bildschirm sind verstreute Kreise zu sehen, und du tippst sie so schnell wie m\xf6glich in der richtigen Reihenfolge an, ohne den Fokus zu verlieren: in der einfachen Version sind das die Zahlen 1-2-3 bis zur letzten, in der schwereren wechselst du zwischen Zahlen und Buchstaben ab, 1-A-2-B-3-C, und springst bei jedem Schritt die Spur.",benefit:"In der reinen Zahlenversion werden visuelles Absuchen und Verarbeitungsgeschwindigkeit trainiert, und in der Zahlen-Buchstaben-Version kommt die kognitive Flexibilit\xe4t hinzu, also die F\xe4higkeit, zwischen zwei Regeln zu wechseln, ohne den Faden zu verlieren. Genau diese Anforderung, das mentale Set umzuschalten, macht den Wechselmodus zu einem klassischen Fenster auf die exekutiven Funktionen.",history:"Sie ging aus Partingtons Pathways Test von 1938 hervor, einer einfachen Papieraufgabe. 1944 wurde sie in die Individual Test Battery der US-Armee aufgenommen und erhielt den Namen Trail Making Test, und in den 1950er-Jahren \xfcbernahm der Neuropsychologe Ralph Reitan sie zur Untersuchung von Hirnsch\xe4den und baute sie in die Halstead-Reitan-Testbatterie ein, wodurch seine Papier-und-Bleistift-Version zu der wurde, die die meisten Kliniken bis heute nutzen.",creator:"Es gibt keinen einzelnen modernen Erfinder. Die erste Version wird dem amerikanischen Psychologen John E. Partington um 1938 zugeschrieben (ver\xf6ffentlicht als Partington & Leiter, 1949); das Zahlen-Buchstaben-Format und der Name stammen von der US-Armee aus dem Jahr 1944, und Ralph Reitan standardisierte und verbreitete sie ab den 1950er-Jahren.",methods:"Lass deine Augen vorauswandern und finde die n\xe4chsten zwei oder drei Ziele, bevor du tippst, statt eines nach dem anderen zu suchen. Halte im Wechselmodus zwei Marken gleichzeitig im Kopf, die n\xe4chste Zahl und den n\xe4chsten Buchstaben, damit dich der Wechsel weniger kostet. Erst Genauigkeit, dann Tempo, denn ein falscher Tipp kostet meist mehr Zeit, als eine Spur langsamer zu sein.",duration:"Kurze Sitzungen funktionieren am besten: eine Handvoll Tafeln \xfcber f\xfcnf bis zehn Minuten, ein paar Mal die Woche. Da die Fortschritte schnell ein Plateau erreichen und es eher ein Sprint als eine Ausdaueraufgabe ist, schl\xe4gt kurzes, h\xe4ufiges \xdcben lange Schinderei-Sitzungen.",research:"Solide belegt ist genau das, was du erwarten w\xfcrdest: Mit \xdcbung wirst du beim Trail Making selbst schneller und treffsicherer, und die Aufgabe ist ein gut validiertes klinisches Ma\xdf f\xfcr Verarbeitungsgeschwindigkeit und Set-Wechsel. Der Sprung von dort zu weiterreichenden Gewinnen ist die schwache Stelle der Beleglage. Gro\xdfe Metaanalysen zum kognitiven Training zeigen, dass die \xdcbertragung auf unge\xfcbte F\xe4higkeiten oder allgemeine Intelligenz gegen null schrumpft, sobald die Studien ordentliche aktive Kontrollgruppen verwenden. Behandle daher jedes Versprechen, es mache dich insgesamt kl\xfcger oder beuge geistigem Abbau vor, mit Vorsicht.",rec:"Nutze den Zahlen-Buchstaben-Modus als deine Hauptaufgabe, denn der Regelwechsel ist das eigentliche Training, und halte die Durchg\xe4nge kurz.",faq:[["Worin besteht der Unterschied zwischen dem Nur-Zahlen-Modus und dem Zahlen-Buchstaben-Modus?","Der Nur-Zahlen-Modus pr\xfcft vor allem, wie schnell du absuchen und in Reihenfolge bringen kannst. Der Zahlen-Buchstaben-Modus f\xfcgt einen st\xe4ndigen Regelwechsel zwischen zwei Folgen hinzu, was die kognitive Flexibilit\xe4t belastet, und deshalb brauchen die Leute daf\xfcr normalerweise etwa doppelt so lange."],["Was gilt als gute Zeit?","Bei gesunden Erwachsenen liegt der Nur-Zahlen-Teil im Schnitt bei rund 30 Sekunden und der Wechselteil bei rund 75 Sekunden, doch das h\xe4ngt stark vom Alter und der genauen Anordnung ab. Vergleiche dich also lieber mit deinen eigenen fr\xfcheren Durchg\xe4ngen als mit einem festen Wert."],["Werde ich dadurch im Alltag kl\xfcger oder schneller?","Ehrlich gesagt nicht in irgendeiner umfassenden Weise, die die Forschung st\xfctzt. Du wirst eindeutig in dieser Aufgabe und bei \xe4hnlichem Absuchen und Wechseln besser, aber die kontrollierte Beleglage f\xfcr eine \xdcbertragung auf die allgemeine Intelligenz oder das t\xe4gliche Leben ist schwach. Genie\xdfe es also als gezieltes Training, nicht als Gehirn-Upgrade."]],variants:"Die Varianten \xe4ndern Ziele und Kanal: nur Zahlen (Teil A) versus abwechselnd Zahlen und Buchstaben (Teil B); farbbasierte Versionen, die zwischen zwei Farben statt Buchstaben wechseln; Form- oder Tierkreis-Versionen f\xfcr nicht-lateinische Alphabete; m\xfcndliche und gehende Versionen, die die Hand ganz weglassen; und l\xe4ngere Raster, die einfach mehr Kreise hinzuf\xfcgen."},pt:{about:"Trail Making \xe9 uma tarefa de velocidade do tipo ligar os pontos. A tela mostra c\xedrculos espalhados e voc\xea toca neles na ordem certa o mais r\xe1pido poss\xedvel sem perder o foco: na vers\xe3o simples s\xe3o os n\xfameros 1-2-3 at\xe9 o \xfaltimo, e na vers\xe3o mais dif\xedcil voc\xea alterna entre n\xfameros e letras, 1-A-2-B-3-C, trocando de trilha a cada passo.",benefit:"Treina a varredura visual e a velocidade de processamento na vers\xe3o s\xf3 com n\xfameros e, al\xe9m disso, a flexibilidade cognitiva, a capacidade de alternar entre duas regras sem perder o lugar, na vers\xe3o n\xfamero-letra. Essa exig\xeancia de troca de conjunto \xe9 o que faz do modo alternado uma janela cl\xe1ssica para a fun\xe7\xe3o executiva.",history:"Surgiu a partir do Teste de Trajetos de Partington, de 1938, uma tarefa simples em papel. Em 1944 foi incorporado \xe0 Bateria de Testes Individuais do Ex\xe9rcito dos EUA e ganhou o nome de Trail Making Test, e na d\xe9cada de 1950 o neuropsic\xf3logo Ralph Reitan o adotou para triagem de les\xf5es cerebrais e o integrou \xe0 bateria Halstead-Reitan, o que tornou a sua vers\xe3o de papel e l\xe1pis aquela que a maioria das cl\xednicas ainda usa hoje.",creator:"N\xe3o h\xe1 um \xfanico inventor moderno. A primeira vers\xe3o \xe9 atribu\xedda ao psic\xf3logo americano John E. Partington, por volta de 1938 (publicada como Partington & Leiter, 1949); o formato n\xfamero-letra e o nome vieram do Ex\xe9rcito dos EUA em 1944, e Ralph Reitan o padronizou e popularizou a partir da d\xe9cada de 1950.",methods:"Corra os olhos \xe0 frente para localizar os pr\xf3ximos dois ou tr\xeas alvos antes de tocar, em vez de ca\xe7ar um de cada vez. No modo alternado, mantenha dois marcadores em mente ao mesmo tempo, o pr\xf3ximo n\xfamero e a pr\xf3xima letra, para que a troca custe menos. Primeiro a precis\xe3o, depois a velocidade, j\xe1 que um toque errado costuma custar mais tempo do que ir um pouquinho mais devagar.",duration:"Sess\xf5es curtas funcionam melhor: um punhado de tabuleiros em cinco a dez minutos, algumas vezes por semana. Como os ganhos estabilizam r\xe1pido e isso \xe9 mais um sprint do que uma tarefa de resist\xeancia, a pr\xe1tica breve e frequente vence as sess\xf5es longas e desgastantes.",research:"O que est\xe1 solidamente demonstrado \xe9 exatamente o que se espera: com a pr\xe1tica voc\xea fica mais r\xe1pido e mais preciso no pr\xf3prio trail making, e a tarefa \xe9 uma medida cl\xednica bem validada de velocidade de processamento e troca de conjunto. O salto da\xed para ganhos mais amplos \xe9 onde a evid\xeancia \xe9 fraca. Grandes meta-an\xe1lises de treino cognitivo concluem que a transfer\xeancia para habilidades n\xe3o treinadas ou para a intelig\xeancia geral encolhe para perto de zero quando os estudos usam grupos de controle ativos adequados, ent\xe3o encare com cautela qualquer promessa de que isso te deixa mais inteligente de modo geral ou afasta o decl\xednio.",rec:"Use o modo n\xfamero-letra como seu desafio principal, j\xe1 que a troca de regras \xe9 onde est\xe1 o treino de verdade, e mantenha as rodadas curtas.",faq:[["Qual \xe9 a diferen\xe7a entre o modo s\xf3 de n\xfameros e o modo n\xfamero-letra?","O modo s\xf3 de n\xfameros testa principalmente a rapidez com que voc\xea consegue varrer e sequenciar. O modo n\xfamero-letra acrescenta a troca constante de regra entre duas sequ\xeancias, o que sobrecarrega a flexibilidade cognitiva, e \xe9 por isso que normalmente leva cerca do dobro do tempo."],["O que conta como um bom tempo?","Para adultos saud\xe1veis, a parte s\xf3 de n\xfameros fica em m\xe9dia em torno de 30 segundos e a parte alternada em torno de 75 segundos, mas isso depende muito da idade e do layout exato, ent\xe3o compare-se com as suas pr\xf3prias rodadas passadas em vez de com um n\xfamero fixo."],["Isso vai me deixar mais inteligente ou mais r\xe1pido no dia a dia?","Sinceramente, n\xe3o de nenhuma forma ampla que a pesquisa sustente. Voc\xea claramente vai melhorar nesta tarefa e em varreduras e trocas parecidas, mas a evid\xeancia controlada de transfer\xeancia para a intelig\xeancia geral ou o funcionamento di\xe1rio \xe9 fraca, ent\xe3o aproveite como pr\xe1tica focada, n\xe3o como upgrade cerebral."]],variants:"As variantes mudam os alvos e o canal: s\xf3 n\xfameros (Parte A) versus n\xfamero-letra alternados (Parte B); vers\xf5es baseadas em cores que alternam entre duas cores em vez de letras; vers\xf5es com formas ou signos do zod\xedaco para alfabetos n\xe3o latinos; vers\xf5es orais e caminhando que abrem m\xe3o da m\xe3o por completo; e grades mais longas que simplesmente acrescentam mais c\xedrculos."},hi:{about:"Trail Making \u090f\u0915 \u092c\u093f\u0902\u0926\u0941-\u091c\u094b\u0921\u093c\u094b \u0930\u092b\u093c\u094d\u0924\u093e\u0930-\u091f\u093e\u0938\u094d\u0915 \u0939\u0948\u0964 \u0938\u094d\u0915\u094d\u0930\u0940\u0928 \u092a\u0930 \u092c\u093f\u0916\u0930\u0947 \u0939\u0941\u090f \u0917\u094b\u0932\u0947 \u0926\u093f\u0916\u0924\u0947 \u0939\u0948\u0902 \u0914\u0930 \u0906\u092a \u0909\u0928\u094d\u0939\u0947\u0902 \u0938\u0939\u0940 \u0915\u094d\u0930\u092e \u092e\u0947\u0902 \u091c\u093f\u0924\u0928\u0940 \u091c\u0932\u094d\u0926\u0940 \u0939\u094b \u0938\u0915\u0947, \u0927\u094d\u092f\u093e\u0928 \u0939\u091f\u093e\u090f \u092c\u093f\u0928\u093e \u091f\u0948\u092a \u0915\u0930\u0924\u0947 \u0939\u0948\u0902: \u0938\u0930\u0932 \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u092e\u0947\u0902 \u092f\u0939 1-2-3 \u0938\u0947 \u0932\u0947\u0915\u0930 \u0906\u0916\u093c\u093f\u0930\u0940 \u0938\u0902\u0916\u094d\u092f\u093e \u0924\u0915 \u0939\u094b\u0924\u093e \u0939\u0948, \u0914\u0930 \u0915\u0920\u093f\u0928 \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u092e\u0947\u0902 \u0906\u092a \u0938\u0902\u0916\u094d\u092f\u093e\u0913\u0902 \u0914\u0930 \u0905\u0915\u094d\u0937\u0930\u094b\u0902 \u0915\u0947 \u092c\u0940\u091a \u092c\u093e\u0930\u0940-\u092c\u093e\u0930\u0940 \u091a\u0932\u0924\u0947 \u0939\u0948\u0902 \u2014 1-A-2-B-3-C \u2014 \u0939\u0930 \u0915\u093c\u0926\u092e \u092a\u0930 \u092a\u091f\u0930\u0940 \u092c\u0926\u0932\u0924\u0947 \u0939\u0941\u090f\u0964",benefit:"\u0938\u093f\u0930\u094d\u092b\u093c-\u0938\u0902\u0916\u094d\u092f\u093e \u0935\u093e\u0932\u0947 \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u092e\u0947\u0902 \u092f\u0939 \u0926\u0943\u0936\u094d\u092f-\u0938\u094d\u0915\u0948\u0928\u093f\u0902\u0917 \u0914\u0930 \u092a\u094d\u0930\u0938\u0902\u0938\u094d\u0915\u0930\u0923-\u0917\u0924\u093f \u0938\u093e\u0927\u0924\u093e \u0939\u0948, \u0914\u0930 \u0909\u0938\u0915\u0947 \u090a\u092a\u0930 \u0938\u0902\u0916\u094d\u092f\u093e-\u0905\u0915\u094d\u0937\u0930 \u0935\u093e\u0932\u0947 \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u092e\u0947\u0902 \u0938\u0902\u091c\u094d\u091e\u093e\u0928\u093e\u0924\u094d\u092e\u0915 \u0932\u091a\u0940\u0932\u093e\u092a\u0928 \u092d\u0940 \u2014 \u092f\u093e\u0928\u0940 \u0905\u092a\u0928\u0940 \u091c\u0917\u0939 \u0916\u094b\u090f \u092c\u093f\u0928\u093e \u0926\u094b \u0928\u093f\u092f\u092e\u094b\u0902 \u0915\u0947 \u092c\u0940\u091a switch \u0915\u0930\u0928\u0947 \u0915\u0940 \u0915\u094d\u0937\u092e\u0924\u093e\u0964 set-switching \u0915\u0940 \u092f\u0939\u0940 \u092e\u093e\u0901\u0917 alternating \u092e\u094b\u0921 \u0915\u094b \u0915\u093e\u0930\u094d\u092f\u0915\u093e\u0930\u0940-\u0915\u093e\u0930\u094d\u092f (executive function) \u0915\u0940 \u090f\u0915 \u0915\u094d\u0932\u093e\u0938\u093f\u0915 \u0916\u093f\u0921\u093c\u0915\u0940 \u092c\u0928\u093e\u0924\u0940 \u0939\u0948\u0964",history:"\u092f\u0939 1938 \u0915\u0947 Partington's Pathways Test \u0938\u0947 \u0928\u093f\u0915\u0932\u093e, \u091c\u094b \u090f\u0915 \u0938\u0930\u0932 \u0915\u093e\u0917\u093c\u091c\u093c\u0940 \u091f\u093e\u0938\u094d\u0915 \u0925\u093e\u0964 1944 \u092e\u0947\u0902 \u0907\u0938\u0947 U.S. Army Individual Test Battery \u092e\u0947\u0902 \u0936\u093e\u092e\u093f\u0932 \u0915\u093f\u092f\u093e \u0917\u092f\u093e \u0914\u0930 \u0907\u0938\u0947 Trail Making Test \u0928\u093e\u092e \u092e\u093f\u0932\u093e; \u0914\u0930 1950 \u0915\u0947 \u0926\u0936\u0915 \u092e\u0947\u0902 \u0928\u094d\u092f\u0942\u0930\u094b\u0938\u093e\u0907\u0915\u094b\u0932\u0949\u091c\u093f\u0938\u094d\u091f Ralph Reitan \u0928\u0947 \u0907\u0938\u0947 \u092e\u0938\u094d\u0924\u093f\u0937\u094d\u0915-\u091a\u094b\u091f \u0915\u0940 \u0938\u094d\u0915\u094d\u0930\u0940\u0928\u093f\u0902\u0917 \u0915\u0947 \u0932\u093f\u090f \u0905\u092a\u0928\u093e\u092f\u093e \u0914\u0930 Halstead-Reitan \u092c\u0948\u091f\u0930\u0940 \u092e\u0947\u0902 \u091c\u094b\u0921\u093c\u093e, \u091c\u093f\u0938\u0938\u0947 \u0909\u0928\u0915\u093e \u0915\u093e\u0917\u093c\u091c\u093c-\u0914\u0930-\u092a\u0947\u0902\u0938\u093f\u0932 \u0935\u093e\u0932\u093e \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0939\u0940 \u0935\u0939 \u092c\u0928 \u0917\u092f\u093e \u091c\u094b \u0906\u091c \u092d\u0940 \u091c\u093c\u094d\u092f\u093e\u0926\u093e\u0924\u0930 \u0915\u094d\u0932\u093f\u0928\u093f\u0915 \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902\u0964",creator:"\u0907\u0938\u0915\u093e \u0915\u094b\u0908 \u090f\u0915 \u0906\u0927\u0941\u0928\u093f\u0915 \u0906\u0935\u093f\u0937\u094d\u0915\u093e\u0930\u0915 \u0928\u0939\u0940\u0902 \u0939\u0948\u0964 \u092a\u0939\u0932\u093e \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0915\u093c\u0930\u0940\u092c 1938 \u092e\u0947\u0902 \u0905\u092e\u0947\u0930\u093f\u0915\u0940 \u092e\u0928\u094b\u0935\u0948\u091c\u094d\u091e\u093e\u0928\u093f\u0915 John E. Partington \u0915\u094b \u0926\u093f\u092f\u093e \u091c\u093e\u0924\u093e \u0939\u0948 (Partington & Leiter, 1949 \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u092a\u094d\u0930\u0915\u093e\u0936\u093f\u0924); \u0938\u0902\u0916\u094d\u092f\u093e-\u0905\u0915\u094d\u0937\u0930 \u0935\u093e\u0932\u093e \u0930\u0942\u092a \u0914\u0930 \u0928\u093e\u092e 1944 \u092e\u0947\u0902 U.S. Army \u0938\u0947 \u0906\u092f\u093e, \u0914\u0930 Ralph Reitan \u0928\u0947 1950 \u0915\u0947 \u0926\u0936\u0915 \u0938\u0947 \u0906\u0917\u0947 \u0907\u0938\u0947 \u092e\u093e\u0928\u0915\u0940\u0915\u0943\u0924 \u0914\u0930 \u0932\u094b\u0915\u092a\u094d\u0930\u093f\u092f \u092c\u0928\u093e\u092f\u093e\u0964",methods:"\u091f\u0948\u092a \u0915\u0930\u0928\u0947 \u0938\u0947 \u092a\u0939\u0932\u0947 \u0928\u091c\u093c\u0930 \u0906\u0917\u0947 \u0926\u094c\u0921\u093c\u093e\u0915\u0930 \u0905\u0917\u0932\u0947 \u0926\u094b-\u0924\u0940\u0928 \u0932\u0915\u094d\u0937\u094d\u092f \u0922\u0942\u0901\u0922 \u0932\u0947\u0902, \u092c\u091c\u093e\u092f \u090f\u0915-\u090f\u0915 \u0915\u0930\u0915\u0947 \u0916\u094b\u091c\u0928\u0947 \u0915\u0947\u0964 alternating \u092e\u094b\u0921 \u092e\u0947\u0902 \u090f\u0915 \u0938\u093e\u0925 \u0926\u094b \u0938\u0942\u091a\u0915 \u092e\u0928 \u092e\u0947\u0902 \u0930\u0916\u0947\u0902 \u2014 \u0905\u0917\u0932\u0940 \u0938\u0902\u0916\u094d\u092f\u093e \u0914\u0930 \u0905\u0917\u0932\u093e \u0905\u0915\u094d\u0937\u0930 \u2014 \u0924\u093e\u0915\u093f switch \u0906\u092a\u0915\u094b \u0915\u092e \u092e\u0939\u0901\u0917\u093e \u092a\u0921\u093c\u0947\u0964 \u092a\u0939\u0932\u0947 \u0938\u091f\u0940\u0915\u0924\u093e, \u092b\u093f\u0930 \u0930\u092b\u093c\u094d\u0924\u093e\u0930, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u090f\u0915 \u0917\u093c\u0932\u0924 \u091f\u0948\u092a \u0906\u092e\u0924\u094c\u0930 \u092a\u0930 \u0925\u094b\u0921\u093c\u093e \u0927\u0940\u092e\u0947 \u091a\u0932\u0928\u0947 \u0938\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0938\u092e\u092f \u0916\u093e \u091c\u093e\u0924\u093e \u0939\u0948\u0964",duration:"\u091b\u094b\u091f\u0947 \u0938\u0924\u094d\u0930 \u0938\u092c\u0938\u0947 \u0905\u091a\u094d\u091b\u0947 \u0930\u0939\u0924\u0947 \u0939\u0948\u0902: \u092a\u093e\u0901\u091a \u0938\u0947 \u0926\u0938 \u092e\u093f\u0928\u091f \u092e\u0947\u0902 \u092e\u0941\u091f\u094d\u0920\u0940 \u092d\u0930 \u092c\u094b\u0930\u094d\u0921, \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u0915\u0941\u091b \u092c\u093e\u0930\u0964 \u091a\u0942\u0901\u0915\u093f \u092b\u093c\u093e\u092f\u0926\u0947 \u091c\u0932\u094d\u0926\u0940 \u090f\u0915 \u091c\u0917\u0939 \u0906\u0915\u0930 \u0920\u0939\u0930 \u091c\u093e\u0924\u0947 \u0939\u0948\u0902 \u0914\u0930 \u092f\u0939 \u0938\u0939\u0928\u0936\u0915\u094d\u0924\u093f \u0915\u0947 \u092c\u091c\u093e\u092f \u090f\u0915 \u0926\u094c\u0921\u093c \u091c\u0948\u0938\u093e \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u091b\u094b\u091f\u093e \u092c\u093e\u0930-\u092c\u093e\u0930 \u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0932\u0902\u092c\u0947 \u0930\u0917\u0921\u093c\u0928\u0947 \u0935\u093e\u0932\u0947 \u0938\u0924\u094d\u0930\u094b\u0902 \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u0939\u0948\u0964",research:"\u091c\u094b \u092a\u0941\u0916\u093c\u094d\u0924\u093e \u0922\u0902\u0917 \u0938\u0947 \u0926\u093f\u0916\u093e \u0939\u0948 \u0935\u0939 \u0920\u0940\u0915 \u0935\u0939\u0940 \u0939\u0948 \u091c\u093f\u0938\u0915\u0940 \u0909\u092e\u094d\u092e\u0940\u0926 \u0939\u094b\u0917\u0940: \u0905\u092d\u094d\u092f\u093e\u0938 \u0938\u0947 \u0906\u092a trail making \u092e\u0947\u0902 \u0939\u0940 \u0924\u0947\u091c\u093c \u0914\u0930 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0938\u091f\u0940\u0915 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u092f\u0939 \u091f\u093e\u0938\u094d\u0915 \u092a\u094d\u0930\u0938\u0902\u0938\u094d\u0915\u0930\u0923-\u0917\u0924\u093f \u0924\u0925\u093e set-switching \u0915\u093e \u090f\u0915 \u0905\u091a\u094d\u091b\u0940 \u0924\u0930\u0939 \u0938\u0924\u094d\u092f\u093e\u092a\u093f\u0924 \u0915\u094d\u0932\u093f\u0928\u093f\u0915\u0932 \u092e\u093e\u092a \u0939\u0948\u0964 \u0935\u0939\u093e\u0901 \u0938\u0947 \u0935\u094d\u092f\u093e\u092a\u0915 \u092b\u093c\u093e\u092f\u0926\u094b\u0902 \u0924\u0915 \u0915\u0940 \u091b\u0932\u093e\u0901\u0917 \u0939\u0940 \u0935\u0939 \u091c\u0917\u0939 \u0939\u0948 \u091c\u0939\u093e\u0901 \u0938\u092c\u0942\u0924 \u0915\u092e\u091c\u093c\u094b\u0930 \u0939\u0948\u0902\u0964 \u0938\u0902\u091c\u094d\u091e\u093e\u0928\u093e\u0924\u094d\u092e\u0915 \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u0915\u0947 \u092c\u0921\u093c\u0947 \u092e\u0947\u091f\u093e-\u0935\u093f\u0936\u094d\u0932\u0947\u0937\u0923 \u092a\u093e\u0924\u0947 \u0939\u0948\u0902 \u0915\u093f \u091c\u092c \u0905\u0927\u094d\u092f\u092f\u0928\u094b\u0902 \u092e\u0947\u0902 \u0938\u0939\u0940 active control \u0938\u092e\u0942\u0939 \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902, \u0924\u094b \u092c\u093f\u0928\u093e-\u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u093f\u0924 \u0915\u094d\u0937\u092e\u0924\u093e\u0913\u0902 \u092f\u093e \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u092c\u0941\u0926\u094d\u0927\u093f \u0924\u0915 \u0938\u094d\u0925\u093e\u0928\u093e\u0902\u0924\u0930\u0923 \u0938\u093f\u0915\u0941\u0921\u093c\u0915\u0930 \u0936\u0942\u0928\u094d\u092f \u0915\u0940 \u0913\u0930 \u091a\u0932\u093e \u091c\u093e\u0924\u093e \u0939\u0948 \u2014 \u0907\u0938\u0932\u093f\u090f \u0907\u0938 \u0935\u093e\u0926\u0947 \u0915\u094b \u0938\u093e\u0935\u0927\u093e\u0928\u0940 \u0938\u0947 \u0932\u0947\u0902 \u0915\u093f \u092f\u0939 \u0906\u092a\u0915\u094b \u0915\u0941\u0932 \u092e\u093f\u0932\u093e\u0915\u0930 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0939\u094b\u0936\u093f\u092f\u093e\u0930 \u092c\u0928\u093e \u0926\u0947\u0924\u093e \u0939\u0948 \u092f\u093e \u0917\u093f\u0930\u093e\u0935\u091f \u0938\u0947 \u092c\u091a\u093e\u0924\u093e \u0939\u0948\u0964",rec:"\u0938\u0902\u0916\u094d\u092f\u093e-\u0905\u0915\u094d\u0937\u0930 \u092e\u094b\u0921 \u0915\u094b \u0905\u092a\u0928\u0940 \u092e\u0941\u0916\u094d\u092f \u091a\u0941\u0928\u094c\u0924\u0940 \u092c\u0928\u093e\u090f\u0901, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u0905\u0938\u0932\u0940 \u0915\u0938\u0930\u0924 \u0928\u093f\u092f\u092e-\u092c\u0926\u0932\u0928\u0947 \u092e\u0947\u0902 \u0939\u0940 \u0939\u0948, \u0914\u0930 \u0926\u094c\u0921\u093c\u0947\u0902 \u091b\u094b\u091f\u0940 \u0930\u0916\u0947\u0902\u0964",faq:[["\u0938\u093f\u0930\u094d\u092b\u093c-\u0938\u0902\u0916\u094d\u092f\u093e \u0914\u0930 \u0938\u0902\u0916\u094d\u092f\u093e-\u0905\u0915\u094d\u0937\u0930 \u092e\u094b\u0921 \u092e\u0947\u0902 \u0915\u094d\u092f\u093e \u092b\u093c\u0930\u094d\u0915\u093c \u0939\u0948?","\u0938\u093f\u0930\u094d\u092b\u093c-\u0938\u0902\u0916\u094d\u092f\u093e \u092e\u094b\u0921 \u091c\u093c\u094d\u092f\u093e\u0926\u093e\u0924\u0930 \u092f\u0939 \u091c\u093e\u0901\u091a\u0924\u093e \u0939\u0948 \u0915\u093f \u0906\u092a \u0915\u093f\u0924\u0928\u0940 \u0924\u0947\u091c\u093c\u0940 \u0938\u0947 \u0938\u094d\u0915\u0948\u0928 \u0915\u0930\u0915\u0947 \u0915\u094d\u0930\u092e \u092c\u0928\u093e \u0938\u0915\u0924\u0947 \u0939\u0948\u0902\u0964 \u0938\u0902\u0916\u094d\u092f\u093e-\u0905\u0915\u094d\u0937\u0930 \u092e\u094b\u0921 \u0926\u094b \u0905\u0928\u0941\u0915\u094d\u0930\u092e\u094b\u0902 \u0915\u0947 \u092c\u0940\u091a \u0932\u0917\u093e\u0924\u093e\u0930 \u0928\u093f\u092f\u092e-\u092c\u0926\u0932\u093e\u0935 \u091c\u094b\u0921\u093c \u0926\u0947\u0924\u093e \u0939\u0948, \u091c\u094b \u0938\u0902\u091c\u094d\u091e\u093e\u0928\u093e\u0924\u094d\u092e\u0915 \u0932\u091a\u0940\u0932\u0947\u092a\u0928 \u092a\u0930 \u092c\u094b\u091d \u0921\u093e\u0932\u0924\u093e \u0939\u0948 \u2014 \u0914\u0930 \u092f\u0939\u0940 \u0935\u091c\u0939 \u0939\u0948 \u0915\u093f \u0907\u0938\u092e\u0947\u0902 \u0932\u094b\u0917\u094b\u0902 \u0915\u094b \u0906\u092e\u0924\u094c\u0930 \u092a\u0930 \u0915\u093c\u0930\u0940\u092c \u0926\u094b\u0917\u0941\u0928\u093e \u0938\u092e\u092f \u0932\u0917\u0924\u093e \u0939\u0948\u0964"],["\u0905\u091a\u094d\u091b\u093e \u0938\u092e\u092f \u0915\u093f\u0938\u0947 \u092e\u093e\u0928\u093e \u091c\u093e\u090f?","\u0938\u094d\u0935\u0938\u094d\u0925 \u0935\u092f\u0938\u094d\u0915\u094b\u0902 \u0915\u0947 \u0932\u093f\u090f \u0938\u093f\u0930\u094d\u092b\u093c-\u0938\u0902\u0916\u094d\u092f\u093e \u0935\u093e\u0932\u093e \u0939\u093f\u0938\u094d\u0938\u093e \u0914\u0938\u0924\u0928 \u0915\u093c\u0930\u0940\u092c 30 \u0938\u0947\u0915\u0902\u0921 \u0914\u0930 \u092c\u093e\u0930\u0940-\u092c\u093e\u0930\u0940 \u0935\u093e\u0932\u093e \u0939\u093f\u0938\u094d\u0938\u093e \u0915\u093c\u0930\u0940\u092c 75 \u0938\u0947\u0915\u0902\u0921 \u0932\u0947\u0924\u093e \u0939\u0948, \u092a\u0930 \u092f\u0947 \u0909\u092e\u094d\u0930 \u0914\u0930 \u0938\u091f\u0940\u0915 \u0932\u0947\u0906\u0909\u091f \u092a\u0930 \u092c\u0939\u0941\u0924 \u0928\u093f\u0930\u094d\u092d\u0930 \u0915\u0930\u0924\u0947 \u0939\u0948\u0902, \u0907\u0938\u0932\u093f\u090f \u0915\u093f\u0938\u0940 \u0924\u092f \u0938\u0902\u0916\u094d\u092f\u093e \u0938\u0947 \u0928\u0939\u0940\u0902, \u092c\u0932\u094d\u0915\u093f \u0905\u092a\u0928\u0940 \u0939\u0940 \u092a\u093f\u091b\u0932\u0940 \u0926\u094c\u0921\u093c\u094b\u0902 \u0938\u0947 \u0916\u093c\u0941\u0926 \u0915\u0940 \u0924\u0941\u0932\u0928\u093e \u0915\u0930\u0947\u0902\u0964"],["\u0915\u094d\u092f\u093e \u0907\u0938\u0938\u0947 \u092e\u0948\u0902 \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0940 \u091c\u093c\u093f\u0902\u0926\u0917\u0940 \u092e\u0947\u0902 \u0939\u094b\u0936\u093f\u092f\u093e\u0930 \u092f\u093e \u0924\u0947\u091c\u093c \u0939\u094b \u091c\u093e\u090a\u0901\u0917\u093e?","\u0908\u092e\u093e\u0928\u0926\u093e\u0930\u0940 \u0938\u0947 \u0915\u0939\u0947\u0902 \u0924\u094b \u0915\u093f\u0938\u0940 \u0935\u094d\u092f\u093e\u092a\u0915 \u0924\u0930\u0940\u0915\u093c\u0947 \u0938\u0947 \u0928\u0939\u0940\u0902, \u091c\u093f\u0938\u0947 \u0936\u094b\u0927 \u0938\u092e\u0930\u094d\u0925\u0928 \u0926\u0947\u0924\u093e \u0939\u094b\u0964 \u0906\u092a \u0938\u093e\u092b\u093c \u0924\u094c\u0930 \u092a\u0930 \u0907\u0938 \u091f\u093e\u0938\u094d\u0915 \u092e\u0947\u0902 \u0914\u0930 \u0907\u0938\u0940 \u091c\u0948\u0938\u0940 \u0938\u094d\u0915\u0948\u0928\u093f\u0902\u0917 \u0924\u0925\u093e switching \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u090f\u0901\u0917\u0947, \u092a\u0930 \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u092c\u0941\u0926\u094d\u0927\u093f \u092f\u093e \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0947 \u0915\u093e\u092e\u0915\u093e\u091c \u0924\u0915 \u0938\u094d\u0925\u093e\u0928\u093e\u0902\u0924\u0930\u0923 \u0915\u0947 \u0928\u093f\u092f\u0902\u0924\u094d\u0930\u093f\u0924 \u0938\u092c\u0942\u0924 \u0915\u092e\u091c\u093c\u094b\u0930 \u0939\u0948\u0902 \u2014 \u0907\u0938\u0932\u093f\u090f \u0907\u0938\u0915\u093e \u092e\u091c\u093c\u093e \u090f\u0915 \u0915\u0947\u0902\u0926\u094d\u0930\u093f\u0924 \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0947 \u0924\u094c\u0930 \u092a\u0930 \u0932\u0947\u0902, \u0926\u093f\u092e\u093e\u0917\u093c\u0940 \u0905\u092a\u0917\u094d\u0930\u0947\u0921 \u0915\u0947 \u0924\u094c\u0930 \u092a\u0930 \u0928\u0939\u0940\u0902\u0964"]],variants:"\u0930\u0942\u092a\u093e\u0902\u0924\u0930 \u0932\u0915\u094d\u0937\u094d\u092f \u0914\u0930 \u092a\u091f\u0930\u0940, \u0926\u094b\u0928\u094b\u0902 \u092c\u0926\u0932\u0924\u0947 \u0939\u0948\u0902: \u0938\u093f\u0930\u094d\u092b\u093c-\u0938\u0902\u0916\u094d\u092f\u093e (Part A) \u092c\u0928\u093e\u092e \u092c\u093e\u0930\u0940-\u092c\u093e\u0930\u0940 \u0938\u0902\u0916\u094d\u092f\u093e-\u0905\u0915\u094d\u0937\u0930 (Part B); \u0930\u0902\u0917-\u0906\u0927\u093e\u0930\u093f\u0924 \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u091c\u094b \u0905\u0915\u094d\u0937\u0930\u094b\u0902 \u0915\u0947 \u092c\u091c\u093e\u092f \u0926\u094b \u0930\u0902\u0917\u094b\u0902 \u0915\u0947 \u092c\u0940\u091a switch \u0915\u0930\u0924\u0947 \u0939\u0948\u0902; \u0917\u093c\u0948\u0930-\u0932\u0948\u091f\u093f\u0928 \u0935\u0930\u094d\u0923\u092e\u093e\u0932\u093e\u0913\u0902 \u0915\u0947 \u0932\u093f\u090f \u0906\u0915\u0943\u0924\u093f \u092f\u093e \u0930\u093e\u0936\u093f \u0935\u093e\u0932\u0947 \u0938\u0902\u0938\u094d\u0915\u0930\u0923; \u092e\u094c\u0916\u093f\u0915 \u0914\u0930 \u091a\u0932\u0924\u0947-\u092b\u093f\u0930\u0924\u0947 \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u091c\u094b \u0939\u093e\u0925 \u0915\u094b \u092a\u0942\u0930\u0940 \u0924\u0930\u0939 \u0939\u091f\u093e \u0926\u0947\u0924\u0947 \u0939\u0948\u0902; \u0914\u0930 \u0932\u0902\u092c\u0947 \u0917\u094d\u0930\u093f\u0921 \u091c\u094b \u092c\u0938 \u0914\u0930 \u0917\u094b\u0932\u0947 \u091c\u094b\u0921\u093c \u0926\u0947\u0924\u0947 \u0939\u0948\u0902\u0964"},zh:{about:"\u8fde\u7ebf\u6d4b\u8bd5\u662f\u4e00\u9879\u8fde\u70b9\u6210\u7ebf\u7684\u901f\u5ea6\u4efb\u52a1\u3002\u5c4f\u5e55\u4e0a\u6563\u5e03\u7740\u4e00\u4e9b\u5706\u5708\uff0c\u4f60\u8981\u5728\u4e0d\u5206\u795e\u7684\u524d\u63d0\u4e0b\u5c3d\u5feb\u6309\u6b63\u786e\u987a\u5e8f\u70b9\u51fb\u5b83\u4eec\uff1a\u5728\u7b80\u5355\u7248\u91cc\u5c31\u662f\u6570\u5b57 1-2-3 \u4e00\u76f4\u70b9\u5230\u6700\u540e\u4e00\u4e2a\uff0c\u5728\u96be\u4e00\u4e9b\u7684\u7248\u91cc\u5219\u8981\u5728\u6570\u5b57\u548c\u5b57\u6bcd\u4e4b\u95f4\u4ea4\u66ff\uff0c1-A-2-B-3-C\uff0c\u6bcf\u8d70\u4e00\u6b65\u90fd\u8981\u5207\u6362\u8f68\u9053\u3002",benefit:"\u5728\u7eaf\u6570\u5b57\u7248\u91cc\uff0c\u5b83\u8bad\u7ec3\u89c6\u89c9\u641c\u7d22\u548c\u52a0\u5de5\u901f\u5ea6\uff1b\u5728\u6570\u5b57-\u5b57\u6bcd\u7248\u91cc\uff0c\u5b83\u5728\u6b64\u57fa\u7840\u4e0a\u8fd8\u8bad\u7ec3\u8ba4\u77e5\u7075\u6d3b\u6027\u2014\u2014\u4e5f\u5c31\u662f\u5728\u4e24\u6761\u89c4\u5219\u4e4b\u95f4\u5207\u6362\u800c\u4e0d\u5f04\u4e22\u4f4d\u7f6e\u7684\u80fd\u529b\u3002\u6b63\u662f\u8fd9\u79cd\u96c6\u5408\u5207\u6362\u7684\u8981\u6c42\uff0c\u4f7f\u4ea4\u66ff\u6a21\u5f0f\u6210\u4e3a\u7aa5\u63a2\u6267\u884c\u529f\u80fd\u7684\u4e00\u6247\u7ecf\u5178\u7a97\u53e3\u3002",history:"\u5b83\u8131\u80ce\u4e8e 1938 \u5e74 Partington \u7684\u8def\u5f84\u6d4b\u8bd5\uff0c\u90a3\u662f\u4e00\u9879\u7b80\u5355\u7684\u7eb8\u7b14\u4efb\u52a1\u30021944 \u5e74\u5b83\u88ab\u7eb3\u5165\u7f8e\u56fd\u9646\u519b\u4e2a\u4eba\u6d4b\u9a8c\u7ec4\uff0c\u5e76\u5f97\u540d\u201c\u8fde\u7ebf\u6d4b\u9a8c\u201d\uff08Trail Making Test\uff09\uff1b1950 \u5e74\u4ee3\uff0c\u795e\u7ecf\u5fc3\u7406\u5b66\u5bb6 Ralph Reitan \u628a\u5b83\u7528\u4e8e\u8111\u635f\u4f24\u7b5b\u67e5\uff0c\u5e76\u5c06\u5176\u7eb3\u5165 Halstead-Reitan \u6d4b\u9a8c\u7ec4\uff0c\u6b63\u662f\u4ed6\u90a3\u4e2a\u7eb8\u7b14\u7248\u672c\uff0c\u6210\u4e86\u5982\u4eca\u591a\u6570\u8bca\u6240\u4ecd\u5728\u4f7f\u7528\u7684\u7248\u672c\u3002",creator:"\u5b83\u6ca1\u6709\u5355\u4e00\u7684\u73b0\u4ee3\u53d1\u660e\u8005\u3002\u6700\u65e9\u7684\u7248\u672c\u5f52\u529f\u4e8e\u7f8e\u56fd\u5fc3\u7406\u5b66\u5bb6 John E. Partington\uff0c\u7ea6\u5728 1938 \u5e74\uff08\u4ee5 Partington & Leiter, 1949 \u53d1\u8868\uff09\uff1b\u6570\u5b57-\u5b57\u6bcd\u683c\u5f0f\u548c\u8fd9\u4e2a\u540d\u5b57\u6765\u81ea 1944 \u5e74\u7684\u7f8e\u56fd\u9646\u519b\uff0c\u800c Ralph Reitan \u4ece 1950 \u5e74\u4ee3\u8d77\u5c06\u5176\u6807\u51c6\u5316\u5e76\u52a0\u4ee5\u63a8\u5e7f\u3002",methods:"\u5728\u70b9\u51fb\u4e4b\u524d\u7528\u773c\u775b\u5f80\u524d\u626b\uff0c\u5148\u9501\u5b9a\u63a5\u4e0b\u6765\u7684\u4e24\u4e09\u4e2a\u76ee\u6807\uff0c\u800c\u4e0d\u662f\u4e00\u4e2a\u4e00\u4e2a\u5730\u627e\u3002\u5728\u4ea4\u66ff\u6a21\u5f0f\u91cc\u540c\u65f6\u8bb0\u4f4f\u4e24\u4e2a\u6307\u9488\u2014\u2014\u4e0b\u4e00\u4e2a\u6570\u5b57\u548c\u4e0b\u4e00\u4e2a\u5b57\u6bcd\u2014\u2014\u8fd9\u6837\u5207\u6362\u7684\u4ee3\u4ef7\u5c31\u66f4\u5c0f\u3002\u5148\u6c42\u51c6\u786e\u518d\u6c42\u5feb\uff0c\u56e0\u4e3a\u70b9\u9519\u901a\u5e38\u6bd4\u7a0d\u6162\u4e00\u70b9\u66f4\u8d39\u65f6\u95f4\u3002",duration:"\u77ed\u65f6\u6bb5\u6548\u679c\u6700\u597d\uff1a\u4e94\u5230\u5341\u5206\u949f\u5185\u505a\u51e0\u5f20\u56fe\u3001\u6bcf\u5468\u51e0\u6b21\u3002\u7531\u4e8e\u8fdb\u6b65\u5f88\u5feb\u4f1a\u8fdb\u5165\u5e73\u53f0\u671f\uff0c\u800c\u4e14\u8fd9\u66f4\u50cf\u662f\u51b2\u523a\u800c\u975e\u8010\u529b\u4efb\u52a1\uff0c\u6240\u4ee5\u7b80\u77ed\u9891\u7e41\u7684\u7ec3\u4e60\u80dc\u8fc7\u53c8\u957f\u53c8\u78e8\u4eba\u7684\u8bad\u7ec3\u3002",research:"\u88ab\u624e\u5b9e\u8bc1\u660e\u7684\uff0c\u6070\u597d\u5c31\u662f\u4f60\u80fd\u6599\u5230\u7684\u90a3\u4e9b\uff1a\u901a\u8fc7\u7ec3\u4e60\uff0c\u4f60\u5728\u8fde\u7ebf\u6d4b\u8bd5\u672c\u8eab\u4e0a\u4f1a\u53d8\u5f97\u66f4\u5feb\u3001\u66f4\u51c6\uff0c\u800c\u4e14\u8fd9\u9879\u4efb\u52a1\u662f\u7ecf\u8fc7\u5145\u5206\u9a8c\u8bc1\u7684\u3001\u8861\u91cf\u52a0\u5de5\u901f\u5ea6\u548c\u96c6\u5408\u5207\u6362\u7684\u4e34\u5e8a\u6307\u6807\u3002\u4ece\u8fd9\u91cc\u8df3\u5230\u66f4\u5bbd\u6cdb\u7684\u6536\u76ca\uff0c\u8bc1\u636e\u5c31\u8584\u5f31\u4e86\u3002\u5bf9\u8ba4\u77e5\u8bad\u7ec3\u7684\u5927\u578b\u5143\u5206\u6790\u53d1\u73b0\uff0c\u4e00\u65e6\u7814\u7a76\u91c7\u7528\u6070\u5f53\u7684\u4e3b\u52a8\u5bf9\u7167\u7ec4\uff0c\u5411\u672a\u8bad\u7ec3\u80fd\u529b\u6216\u4e00\u822c\u667a\u529b\u7684\u8fc1\u79fb\u5c31\u4f1a\u7f29\u5411\u96f6\uff0c\u6240\u4ee5\u5bf9\u4efb\u4f55\u201c\u5b83\u80fd\u8ba9\u4f60\u6574\u4f53\u66f4\u806a\u660e\u201d\u6216\u201c\u80fd\u9632\u6b62\u8870\u9000\u201d\u7684\u627f\u8bfa\u90fd\u8981\u4fdd\u6301\u8c28\u614e\u3002",rec:"\u628a\u6570\u5b57-\u5b57\u6bcd\u6a21\u5f0f\u5f53\u4f5c\u4f60\u7684\u4e3b\u8981\u6311\u6218\uff0c\u56e0\u4e3a\u89c4\u5219\u5207\u6362\u624d\u662f\u771f\u6b63\u51fa\u529b\u7684\u5730\u65b9\uff0c\u5e76\u4e14\u628a\u6bcf\u8f6e\u63a7\u5236\u5f97\u77ed\u4e00\u4e9b\u3002",faq:[["\u7eaf\u6570\u5b57\u6a21\u5f0f\u548c\u6570\u5b57-\u5b57\u6bcd\u6a21\u5f0f\u6709\u4ec0\u4e48\u533a\u522b\uff1f","\u7eaf\u6570\u5b57\u6a21\u5f0f\u4e3b\u8981\u6d4b\u7684\u662f\u4f60\u626b\u89c6\u548c\u6392\u5e8f\u7684\u901f\u5ea6\u3002\u6570\u5b57-\u5b57\u6bcd\u6a21\u5f0f\u5219\u5728\u4e24\u4e2a\u5e8f\u5217\u4e4b\u95f4\u4e0d\u65ad\u5207\u6362\u89c4\u5219\uff0c\u8fd9\u4f1a\u52a0\u91cd\u8ba4\u77e5\u7075\u6d3b\u6027\u7684\u8d1f\u8377\uff0c\u8fd9\u4e5f\u662f\u4e3a\u4ec0\u4e48\u4eba\u4eec\u901a\u5e38\u8981\u82b1\u4e0a\u5927\u7ea6\u4e24\u500d\u7684\u65f6\u95f4\u3002"],["\u4ec0\u4e48\u6837\u7684\u65f6\u95f4\u7b97\u597d\uff1f","\u5bf9\u5065\u5eb7\u6210\u5e74\u4eba\u6765\u8bf4\uff0c\u7eaf\u6570\u5b57\u90e8\u5206\u5e73\u5747\u7ea6 30 \u79d2\uff0c\u4ea4\u66ff\u90e8\u5206\u7ea6 75 \u79d2\uff0c\u4f46\u8fd9\u5f88\u5927\u7a0b\u5ea6\u4e0a\u53d6\u51b3\u4e8e\u5e74\u9f84\u548c\u5177\u4f53\u7684\u5e03\u5c40\uff0c\u6240\u4ee5\u62ff\u81ea\u5df1\u8ddf\u81ea\u5df1\u8fc7\u53bb\u7684\u6210\u7ee9\u6bd4\uff0c\u6bd4\u8ddf\u4e00\u4e2a\u56fa\u5b9a\u6570\u5b57\u6bd4\u66f4\u9760\u8c31\u3002"],["\u8fd9\u4f1a\u8ba9\u6211\u5728\u65e5\u5e38\u751f\u6d3b\u4e2d\u66f4\u806a\u660e\u6216\u66f4\u5feb\u5417\uff1f","\u8bf4\u5b9e\u8bdd\uff0c\u6ca1\u6709\u4efb\u4f55\u7814\u7a76\u652f\u6301\u7684\u5bbd\u6cdb\u6548\u679c\u3002\u4f60\u663e\u7136\u4f1a\u5728\u8fd9\u9879\u4efb\u52a1\u4ee5\u53ca\u7c7b\u4f3c\u7684\u626b\u89c6\u548c\u5207\u6362\u4e0a\u53d8\u5f97\u66f4\u597d\uff0c\u4f46\u5411\u4e00\u822c\u667a\u529b\u6216\u65e5\u5e38\u529f\u80fd\u8fc1\u79fb\u7684\u5bf9\u7167\u8bc1\u636e\u5f88\u8584\u5f31\uff0c\u6240\u4ee5\u628a\u5b83\u5f53\u4f5c\u5b9a\u5411\u7ec3\u4e60\u6765\u4eab\u53d7\uff0c\u800c\u4e0d\u662f\u5927\u8111\u5347\u7ea7\u3002"]],variants:"\u5404\u79cd\u53d8\u4f53\u6539\u53d8\u7684\u662f\u76ee\u6807\u548c\u5207\u6362\u7684\u7ef4\u5ea6\uff1a\u7eaf\u6570\u5b57\uff08A \u90e8\u5206\uff09\u5bf9\u4ea4\u66ff\u6570\u5b57-\u5b57\u6bcd\uff08B \u90e8\u5206\uff09\uff1b\u57fa\u4e8e\u989c\u8272\u7684\u7248\u672c\u5728\u4e24\u79cd\u989c\u8272\u4e4b\u95f4\u5207\u6362\u800c\u4e0d\u662f\u7528\u5b57\u6bcd\uff1b\u4e3a\u975e\u62c9\u4e01\u5b57\u6bcd\u51c6\u5907\u7684\u5f62\u72b6\u6216\u661f\u5ea7\u7248\u672c\uff1b\u5b8c\u5168\u4e0d\u7528\u624b\u7684\u53e3\u5934\u7248\u548c\u884c\u8d70\u7248\uff1b\u4ee5\u53ca\u53ea\u662f\u7b80\u5355\u52a0\u66f4\u591a\u5706\u5708\u7684\u66f4\u5927\u7f51\u683c\u3002"}},"visual-search":{ru:{about:"\u0412 \xab\u0412\u0438\u0437\u0443\u0430\u043b\u044c\u043d\u043e\u043c \u043f\u043e\u0438\u0441\u043a\u0435\xbb \u043f\u0435\u0440\u0435\u0434 \u0432\u0430\u043c\u0438 \u043f\u043e\u043b\u0435 \u043e\u0431\u044a\u0435\u043a\u0442\u043e\u0432, \u0438 \u043d\u0443\u0436\u043d\u043e \u043a\u0430\u043a \u043c\u043e\u0436\u043d\u043e \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u043d\u0430\u0439\u0442\u0438 \u0441\u0440\u0435\u0434\u0438 \u043e\u0442\u0432\u043b\u0435\u043a\u0430\u044e\u0449\u0438\u0445 \u043e\u0434\u0438\u043d \u0437\u0430\u0434\u0430\u043d\u043d\u044b\u0439 \u043e\u0431\u044a\u0435\u043a\u0442 \u0438 \u043d\u0430\u0436\u0430\u0442\u044c \u043d\u0430 \u043d\u0435\u0433\u043e. \u0418\u043d\u043e\u0433\u0434\u0430 \u0446\u0435\u043b\u044c \u0432\u044b\u0434\u0435\u043b\u044f\u0435\u0442\u0441\u044f \u043e\u0434\u043d\u0438\u043c \u043f\u0440\u0438\u0437\u043d\u0430\u043a\u043e\u043c, \u043d\u0430\u043f\u0440\u0438\u043c\u0435\u0440 \u0435\u0434\u0438\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u0430\u044f \u043a\u0440\u0430\u0441\u043d\u0430\u044f \u0442\u043e\u0447\u043a\u0430 \u0441\u0440\u0435\u0434\u0438 \u0441\u0438\u043d\u0438\u0445; \u0438\u043d\u043e\u0433\u0434\u0430 \u0436\u0435 \u043e\u043d\u0430 \u0441\u043e\u0432\u043f\u0430\u0434\u0430\u0435\u0442 \u0441 \u043e\u0441\u0442\u0430\u043b\u044c\u043d\u044b\u043c\u0438 \u043f\u043e \u0432\u0441\u0435\u043c \u043f\u0440\u0438\u0437\u043d\u0430\u043a\u0430\u043c \u0438 \u0443\u043d\u0438\u043a\u0430\u043b\u044c\u043d\u0430 \u043b\u0438\u0448\u044c \u0438\u0445 \u0441\u043e\u0447\u0435\u0442\u0430\u043d\u0438\u0435\u043c, \u0438 \u0442\u043e\u0433\u0434\u0430 \u043f\u0440\u0438\u0445\u043e\u0434\u0438\u0442\u0441\u044f \u043f\u0440\u043e\u0432\u0435\u0440\u044f\u0442\u044c \u043e\u0431\u044a\u0435\u043a\u0442\u044b \u043f\u043e \u043e\u0434\u043d\u043e\u043c\u0443.",benefit:"\u0423\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u0435 \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u0438\u0437\u0431\u0438\u0440\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0435 \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u0435 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u0438 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u043e\u0441\u043c\u043e\u0442\u0440\u0430 \u0441\u0446\u0435\u043d\u044b: \u0443\u043c\u0435\u043d\u0438\u0435 \u043e\u0442\u0441\u0435\u043a\u0430\u0442\u044c \u043b\u0438\u0448\u043d\u0435\u0435, \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0442\u044c \u0432 \u0433\u043e\u043b\u043e\u0432\u0435 \u043f\u0440\u0438\u0437\u043d\u0430\u043a\u0438 \u0446\u0435\u043b\u0438 \u0438 \u0431\u044b\u0441\u0442\u0440\u043e \u0440\u0435\u0448\u0430\u0442\u044c, \u043f\u043e\u0434\u0445\u043e\u0434\u0438\u0442 \u043b\u0438 \u043e\u0447\u0435\u0440\u0435\u0434\u043d\u043e\u0439 \u043e\u0431\u044a\u0435\u043a\u0442. \u0421 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u043e\u0439 \u043f\u043e\u0438\u0441\u043a \u0443\u0441\u043a\u043e\u0440\u044f\u0435\u0442\u0441\u044f, \u0430 \u043f\u043e\u043b\u0435\u0437\u043d\u043e\u0435 \u043f\u043e\u043b\u0435 \u0437\u0440\u0435\u043d\u0438\u044f, \u0442\u0430 \u043e\u0431\u043b\u0430\u0441\u0442\u044c \u0432\u043e\u043a\u0440\u0443\u0433 \u0442\u043e\u0447\u043a\u0438 \u0432\u0437\u0433\u043b\u044f\u0434\u0430, \u043a\u043e\u0442\u043e\u0440\u0443\u044e \u0432\u044b \u043e\u0445\u0432\u0430\u0442\u044b\u0432\u0430\u0435\u0442\u0435 \u0441\u0440\u0430\u0437\u0443, \u043a\u0430\u043a \u043f\u0440\u0430\u0432\u0438\u043b\u043e \u0440\u0430\u0441\u0448\u0438\u0440\u044f\u0435\u0442\u0441\u044f.",history:"\u0417\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0439 \u043f\u043e\u0438\u0441\u043a \u043a\u0430\u043a \u043b\u0430\u0431\u043e\u0440\u0430\u0442\u043e\u0440\u043d\u044b\u0439 \u043c\u0435\u0442\u043e\u0434 \u043e\u0444\u043e\u0440\u043c\u0438\u043b\u0441\u044f \u0432 \u043d\u0430\u0447\u0430\u043b\u0435 1960-\u0445 \u0443 \u0423\u043b\u044c\u0440\u0438\u043a\u0430 \u041d\u0430\u0439\u0441\u0441\u0435\u0440\u0430, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u0437\u0430\u043c\u0435\u0440\u044f\u043b, \u043a\u0430\u043a \u043b\u044e\u0434\u0438 \u043f\u0440\u043e\u0441\u043c\u0430\u0442\u0440\u0438\u0432\u0430\u044e\u0442 \u0441\u0442\u043e\u043b\u0431\u0446\u044b \u0431\u0443\u043a\u0432 \u0432 \u043f\u043e\u0438\u0441\u043a\u0430\u0445 \u0446\u0435\u043b\u0438. \u041a\u043b\u044e\u0447\u0435\u0432\u044b\u043c \u0434\u043b\u044f \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u0438 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f \u043e\u043d \u0441\u0442\u0430\u043b \u0432 1980 \u0433\u043e\u0434\u0443, \u043a\u043e\u0433\u0434\u0430 \u043d\u0430 \u043d\u0451\u043c \u043f\u0440\u043e\u0432\u0435\u0440\u044f\u043b\u0438 \u043a\u0440\u0443\u043f\u043d\u0443\u044e \u0442\u0435\u043e\u0440\u0438\u044e, \u0430 \u043e\u0442\u0442\u0443\u0434\u0430 \u0440\u0430\u0437\u043e\u0448\u0451\u043b\u0441\u044f \u0432 \u044d\u0440\u0433\u043e\u043d\u043e\u043c\u0438\u043a\u0443, \u0440\u0430\u0434\u0438\u043e\u043b\u043e\u0433\u0438\u044e \u0438 \u0434\u043e\u0441\u043c\u043e\u0442\u0440 \u0432 \u0430\u044d\u0440\u043e\u043f\u043e\u0440\u0442\u0430\u0445 \u0438 \u0432 \u043a\u043e\u043d\u0446\u0435 \u043a\u043e\u043d\u0446\u043e\u0432 \u043f\u043e\u043f\u0430\u043b \u0432 \u043f\u043e\u0442\u0440\u0435\u0431\u0438\u0442\u0435\u043b\u044c\u0441\u043a\u0438\u0435 \u043f\u0440\u0438\u043b\u043e\u0436\u0435\u043d\u0438\u044f \u0434\u043b\u044f \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0438 \u043c\u043e\u0437\u0433\u0430.",creator:"\u0415\u0434\u0438\u043d\u043e\u0433\u043e \u0430\u0432\u0442\u043e\u0440\u0430 \u0443 \u0441\u0430\u043c\u043e\u0433\u043e \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u044f \u043d\u0435\u0442. \u0421\u0430\u043c \u043c\u0435\u0442\u043e\u0434 \u043f\u043e\u0438\u0441\u043a\u0430 \u043e\u0431\u044b\u0447\u043d\u043e \u0441\u0432\u044f\u0437\u044b\u0432\u0430\u044e\u0442 \u0441 \u0423\u043b\u044c\u0440\u0438\u043a\u043e\u043c \u041d\u0430\u0439\u0441\u0441\u0435\u0440\u043e\u043c \u0438 \u043d\u0430\u0447\u0430\u043b\u043e\u043c 1960-\u0445, \u0430 \u0448\u0438\u0440\u043e\u043a\u0443\u044e \u0438\u0437\u0432\u0435\u0441\u0442\u043d\u043e\u0441\u0442\u044c \u0435\u043c\u0443 \u043f\u0440\u0438\u043d\u0435\u0441\u043b\u0438 \u042d\u043d\u043d \u0422\u0440\u0435\u0439\u0441\u043c\u0430\u043d \u0438 \u0413\u044d\u0440\u0440\u0438 \u0413\u0435\u043b\u0435\u0439\u0434 \u0432 \u0441\u0442\u0430\u0442\u044c\u0435 1980 \u0433\u043e\u0434\u0430 \xab\u0422\u0435\u043e\u0440\u0438\u044f \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f \u043d\u0430 \u043e\u0441\u043d\u043e\u0432\u0435 \u0438\u043d\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u0438 \u043f\u0440\u0438\u0437\u043d\u0430\u043a\u043e\u0432\xbb: \u043d\u0430 \u043e\u043f\u044b\u0442\u0430\u0445 \u0441\u043e \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u043c \u043f\u043e\u0438\u0441\u043a\u043e\u043c \u043e\u043d\u0438 \u043f\u043e\u043a\u0430\u0437\u0430\u043b\u0438, \u0447\u0442\u043e \u043e\u0442\u0434\u0435\u043b\u044c\u043d\u044b\u0435 \u043f\u0440\u0438\u0437\u043d\u0430\u043a\u0438 \u043d\u0430\u0445\u043e\u0434\u044f\u0442\u0441\u044f \u043f\u0430\u0440\u0430\u043b\u043b\u0435\u043b\u044c\u043d\u043e, \u0430 \u0438\u0445 \u0441\u043e\u0447\u0435\u0442\u0430\u043d\u0438\u044f \u043f\u0440\u0438\u0445\u043e\u0434\u0438\u0442\u0441\u044f \u043f\u0435\u0440\u0435\u0431\u0438\u0440\u0430\u0442\u044c \u043e\u0431\u044a\u0435\u043a\u0442 \u0437\u0430 \u043e\u0431\u044a\u0435\u043a\u0442\u043e\u043c.",methods:"\u041d\u0435 \u0437\u0430\u043c\u0438\u0440\u0430\u0439\u0442\u0435 \u043d\u0430 \u043e\u0434\u043d\u043e\u0439 \u0442\u043e\u0447\u043a\u0435 \u0432 \u043e\u0436\u0438\u0434\u0430\u043d\u0438\u0438: \u0432\u0435\u0434\u0438\u0442\u0435 \u0432\u0437\u0433\u043b\u044f\u0434 \u043f\u043e \u043f\u043e\u043b\u044e \u0440\u043e\u0432\u043d\u044b\u043c, \u0443\u043f\u043e\u0440\u044f\u0434\u043e\u0447\u0435\u043d\u043d\u044b\u043c \u043c\u0430\u0440\u0448\u0440\u0443\u0442\u043e\u043c, \u0430 \u043d\u0435 \u0441\u043a\u0430\u0447\u0438\u0442\u0435 \u043f\u043e \u043d\u0435\u043c\u0443 \u0445\u0430\u043e\u0442\u0438\u0447\u043d\u043e. \u041f\u0435\u0440\u0435\u0434 \u0441\u0442\u0430\u0440\u0442\u043e\u043c \u0447\u0451\u0442\u043a\u043e \u0437\u0430\u0444\u0438\u043a\u0441\u0438\u0440\u0443\u0439\u0442\u0435 \u0432 \u0443\u043c\u0435 \u043f\u0440\u0438\u0437\u043d\u0430\u043a \u0446\u0435\u043b\u0438, \u0430 \u0432 \u043f\u0440\u043e\u0431\u0430\u0445 \u043d\u0430 \u0441\u043e\u0447\u0435\u0442\u0430\u043d\u0438\u0435, \u0433\u0434\u0435 \u043d\u0438\u0447\u0435\u0433\u043e \u0441\u0430\u043c\u043e \u043d\u0435 \u0432\u044b\u0441\u043a\u0430\u043a\u0438\u0432\u0430\u0435\u0442, \u043d\u0435 \u0442\u043e\u0440\u043e\u043f\u0438\u0442\u0435\u0441\u044c \u0438 \u043f\u0440\u0438\u043c\u0438\u0442\u0435, \u0447\u0442\u043e \u043e\u0431\u044a\u0435\u043a\u0442\u044b \u043f\u0440\u0438\u0434\u0451\u0442\u0441\u044f \u043f\u0440\u043e\u0432\u0435\u0440\u044f\u0442\u044c \u043f\u043e \u043e\u0447\u0435\u0440\u0435\u0434\u0438. \u041f\u0440\u0438\u0431\u0430\u0432\u043b\u044f\u0439\u0442\u0435 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u043b\u0438\u0448\u044c \u0442\u043e\u0433\u0434\u0430, \u043a\u043e\u0433\u0434\u0430 \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u044c \u0441\u0442\u0430\u0431\u0438\u043b\u044c\u043d\u0430: \u0441\u043b\u0443\u0447\u0430\u0439\u043d\u044b\u0435 \u043f\u0440\u043e\u043c\u0430\u0445\u0438 \u043e\u0431\u0445\u043e\u0434\u044f\u0442\u0441\u044f \u0434\u043e\u0440\u043e\u0436\u0435, \u0447\u0435\u043c \u0447\u0443\u0442\u044c \u0431\u043e\u043b\u0435\u0435 \u043c\u0435\u0434\u043b\u0435\u043d\u043d\u044b\u0439 \u043e\u0441\u043c\u043e\u0442\u0440.",duration:"\u041b\u0443\u0447\u0448\u0435 \u0432\u0441\u0435\u0433\u043e \u0440\u0430\u0431\u043e\u0442\u0430\u044e\u0442 \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u0435 \u0447\u0430\u0441\u0442\u044b\u0435 \u043f\u043e\u0434\u0445\u043e\u0434\u044b: \u043f\u0440\u0438\u043c\u0435\u0440\u043d\u043e \u043f\u043e 5\u201310 \u043c\u0438\u043d\u0443\u0442 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0440\u0430\u0437 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e. \u0417\u0430\u043a\u0430\u043d\u0447\u0438\u0432\u0430\u0439\u0442\u0435, \u043a\u043e\u0433\u0434\u0430 \u0432\u0440\u0435\u043c\u044f \u0440\u0435\u0430\u043a\u0446\u0438\u0438 \u043d\u0430\u0447\u0438\u043d\u0430\u0435\u0442 \u043f\u043e\u043b\u0437\u0442\u0438 \u0432\u0432\u0435\u0440\u0445, \u0430 \u0447\u0438\u0441\u043b\u043e \u043e\u0448\u0438\u0431\u043e\u043a \u0440\u0430\u0441\u0442\u0451\u0442, \u043f\u043e\u0442\u043e\u043c\u0443 \u0447\u0442\u043e \u0443\u0441\u0442\u0430\u043b\u044b\u0439 \u043f\u043e\u0438\u0441\u043a \u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u0441\u044f \u043d\u0435\u0431\u0440\u0435\u0436\u043d\u044b\u043c \u0438 \u043d\u0443\u0436\u043d\u044b\u0435 \u043d\u0430\u0432\u044b\u043a\u0438 \u0443\u0436\u0435 \u043d\u0435 \u0437\u0430\u043a\u0440\u0435\u043f\u043b\u044f\u044e\u0442\u0441\u044f.",research:"\u041d\u0430\u0434\u0451\u0436\u043d\u0435\u0435 \u0432\u0441\u0435\u0433\u043e \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043d\u043e \u0440\u043e\u0432\u043d\u043e \u0442\u043e, \u0447\u0435\u0433\u043e \u0438 \u0441\u043b\u0435\u0434\u0443\u0435\u0442 \u043e\u0436\u0438\u0434\u0430\u0442\u044c: \u0432\u044b \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u0438 \u0442\u043e\u0447\u043d\u0435\u0435 \u0441\u043f\u0440\u0430\u0432\u043b\u044f\u0435\u0442\u0435\u0441\u044c \u0441 \u0441\u0430\u043c\u0438\u043c \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u043c \u043f\u043e\u0438\u0441\u043a\u043e\u043c, \u0430 \u0431\u043b\u0438\u0437\u043a\u0438\u0435 \u043f\u043e \u0441\u0443\u0442\u0438 \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0438 \u0434\u043e\u043a\u0430\u0437\u0430\u043d\u043d\u043e \u0440\u0430\u0441\u0448\u0438\u0440\u044f\u044e\u0442 \u043f\u043e\u043b\u0435\u0437\u043d\u043e\u0435 \u043f\u043e\u043b\u0435 \u0437\u0440\u0435\u043d\u0438\u044f. \u0421 \u0433\u0440\u043e\u043c\u043a\u0438\u043c\u0438 \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f\u043c\u0438 \u0432\u0441\u0451 \u043a\u0443\u0434\u0430 \u0441\u043b\u0430\u0431\u0435\u0435. \u0423 \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0438 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u0438 \u043e\u0431\u0440\u0430\u0431\u043e\u0442\u043a\u0438 \u0438 \u043f\u043e\u043b\u0435\u0437\u043d\u043e\u0433\u043e \u043f\u043e\u043b\u044f \u0437\u0440\u0435\u043d\u0438\u044f \u0435\u0441\u0442\u044c \u043e\u0434\u043d\u0438 \u0438\u0437 \u043b\u0443\u0447\u0448\u0438\u0445 \u0432 \u044d\u0442\u043e\u0439 \u043e\u0431\u043b\u0430\u0441\u0442\u0438 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442\u043e\u0432 \u0432 \u0440\u0435\u0430\u043b\u044c\u043d\u043e\u0439 \u0436\u0438\u0437\u043d\u0438, \u0432\u043a\u043b\u044e\u0447\u0430\u044f \u0432\u043b\u0438\u044f\u043d\u0438\u0435 \u043d\u0430 \u043f\u043e\u0436\u0438\u043b\u044b\u0445 \u0432\u043e\u0434\u0438\u0442\u0435\u043b\u0435\u0439, \u043d\u043e \u0438 \u043e\u043d\u0438 \u043e\u0441\u043f\u0430\u0440\u0438\u0432\u0430\u044e\u0442\u0441\u044f, \u0430 \u0437\u0430\u044f\u0432\u043b\u0435\u043d\u0438\u044f \u043e \u0440\u043e\u0441\u0442\u0435 \u043e\u0431\u0449\u0435\u0433\u043e \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442\u0430 \u0438\u043b\u0438 \u043f\u0440\u0435\u0434\u043e\u0442\u0432\u0440\u0430\u0449\u0435\u043d\u0438\u0438 \u043a\u043e\u0433\u043d\u0438\u0442\u0438\u0432\u043d\u043e\u0433\u043e \u0441\u043f\u0430\u0434\u0430 \u043f\u043e \u0431\u043e\u043b\u044c\u0448\u0435\u0439 \u0447\u0430\u0441\u0442\u0438 \u043d\u0435 \u0434\u043e\u043a\u0430\u0437\u0430\u043d\u044b, \u0442\u0430\u043a \u0447\u0442\u043e \u043a \u0433\u0440\u043e\u043c\u043a\u0438\u043c \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f\u043c \u0441\u0442\u043e\u0438\u0442 \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u044c\u0441\u044f \u043e\u0441\u0442\u043e\u0440\u043e\u0436\u043d\u043e.",rec:"\u0414\u0435\u0440\u0436\u0438\u0442\u0435 \u0432\u0437\u0433\u043b\u044f\u0434 \u0431\u043b\u0438\u0436\u0435 \u043a \u0446\u0435\u043d\u0442\u0440\u0443 \u0438 \u0434\u0430\u0439\u0442\u0435 \u0440\u0430\u0431\u043e\u0442\u0430\u0442\u044c \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044e; \u043d\u0435 \u043f\u043e\u0434\u0434\u0430\u0432\u0430\u0439\u0442\u0435\u0441\u044c \u0440\u0435\u0444\u043b\u0435\u043a\u0441\u0443 \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043a\u0438 \u043c\u0435\u0442\u0430\u0442\u044c\u0441\u044f \u0433\u043b\u0430\u0437\u0430\u043c\u0438 \u043f\u043e \u043a\u0430\u0436\u0434\u043e\u043c\u0443 \u043e\u0431\u044a\u0435\u043a\u0442\u0443, \u043e\u0441\u043e\u0431\u0435\u043d\u043d\u043e \u043a\u043e\u0433\u0434\u0430 \u043d\u0438\u0447\u0442\u043e \u043d\u0435 \u0432\u044b\u0441\u043a\u0430\u043a\u0438\u0432\u0430\u0435\u0442 \u0441\u0430\u043c\u043e.",faq:[["\u041f\u043e\u0447\u0435\u043c\u0443 \u0446\u0435\u043b\u044c \u0442\u043e \u0432\u044b\u0441\u043a\u0430\u043a\u0438\u0432\u0430\u0435\u0442 \u043c\u0433\u043d\u043e\u0432\u0435\u043d\u043d\u043e, \u0442\u043e \u0438\u0449\u0435\u0442\u0441\u044f \u0446\u0435\u043b\u0443\u044e \u0432\u0435\u0447\u043d\u043e\u0441\u0442\u044c?","\u041a\u043e\u0433\u0434\u0430 \u0446\u0435\u043b\u044c \u043e\u0442\u043b\u0438\u0447\u0430\u0435\u0442\u0441\u044f \u043e\u0434\u043d\u0438\u043c \u0431\u0430\u0437\u043e\u0432\u044b\u043c \u043f\u0440\u0438\u0437\u043d\u0430\u043a\u043e\u043c, \u043d\u0430\u043f\u0440\u0438\u043c\u0435\u0440 \u0446\u0432\u0435\u0442\u043e\u043c \u0438\u043b\u0438 \u043d\u0430\u043a\u043b\u043e\u043d\u043e\u043c, \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u0430\u044f \u0441\u0438\u0441\u0442\u0435\u043c\u0430 \u0437\u0430\u043c\u0435\u0447\u0430\u0435\u0442 \u0435\u0451 \u043f\u043e\u0447\u0442\u0438 \u043f\u0430\u0440\u0430\u043b\u043b\u0435\u043b\u044c\u043d\u043e, \u0438 \u043e\u043d\u0430 \u0431\u0443\u0434\u0442\u043e \u0432\u044b\u0441\u043a\u0430\u043a\u0438\u0432\u0430\u0435\u0442 \u0441\u0430\u043c\u0430. \u041a\u043e\u0433\u0434\u0430 \u0436\u0435 \u043e\u043d\u0430 \u043e\u0442\u043b\u0438\u0447\u0430\u0435\u0442\u0441\u044f \u043b\u0438\u0448\u044c \u0441\u043e\u0447\u0435\u0442\u0430\u043d\u0438\u0435\u043c \u043f\u0440\u0438\u0437\u043d\u0430\u043a\u043e\u0432, \u043e\u0431\u0449\u0438\u0445 \u0441 \u043e\u0442\u0432\u043b\u0435\u043a\u0430\u044e\u0449\u0438\u043c\u0438, \u043e\u0431\u044a\u0435\u043a\u0442\u044b \u043f\u0440\u0438\u0445\u043e\u0434\u0438\u0442\u0441\u044f \u043e\u0441\u043c\u0430\u0442\u0440\u0438\u0432\u0430\u0442\u044c \u0431\u043e\u043b\u0435\u0435 \u0438\u043b\u0438 \u043c\u0435\u043d\u0435\u0435 \u043f\u043e \u043e\u0434\u043d\u043e\u043c\u0443, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u044d\u0442\u043e \u043e\u0449\u0443\u0449\u0430\u0435\u0442\u0441\u044f \u043c\u0435\u0434\u043b\u0435\u043d\u043d\u043e \u0438 \u0441 \u0443\u0441\u0438\u043b\u0438\u0435\u043c."],["\u0421\u0442\u0430\u043d\u0443 \u043b\u0438 \u044f \u0431\u043b\u0430\u0433\u043e\u0434\u0430\u0440\u044f \u044d\u0442\u043e\u043c\u0443 \u0431\u044b\u0441\u0442\u0440\u0435\u0435 \u0437\u0430\u043c\u0435\u0447\u0430\u0442\u044c \u0432\u0435\u0449\u0438 \u0432 \u0436\u0438\u0437\u043d\u0438, \u043d\u0430\u043f\u0440\u0438\u043c\u0435\u0440 \u0434\u0440\u0443\u0433\u0430 \u0432 \u0442\u043e\u043b\u043f\u0435?","\u0412 \u0441\u0430\u043c\u043e\u043c \u0442\u0430\u043a\u043e\u043c \u043f\u043e\u0438\u0441\u043a\u0435 \u0432\u044b \u0441\u0442\u0430\u0431\u0438\u043b\u044c\u043d\u043e \u0441\u0442\u0430\u043d\u0435\u0442\u0435 \u043b\u0443\u0447\u0448\u0435, \u0438 \u043e\u0441\u043c\u043e\u0442\u0440 \u0441\u0446\u0435\u043d\u044b, \u0432\u043e\u0437\u043c\u043e\u0436\u043d\u043e, \u0441\u0442\u0430\u043d\u0435\u0442 \u0447\u0443\u0442\u044c \u044d\u0444\u0444\u0435\u043a\u0442\u0438\u0432\u043d\u0435\u0435. \u0410 \u0432\u043e\u0442 \u043f\u0435\u0440\u0435\u043d\u0435\u0441\u0451\u0442\u0441\u044f \u043b\u0438 \u044d\u0442\u043e \u043d\u0430 \u043f\u043e\u0432\u0441\u0435\u0434\u043d\u0435\u0432\u043d\u044b\u0435 \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u0438, \u043d\u0435 \u0434\u043e\u043a\u0430\u0437\u0430\u043d\u043e \u0443\u0431\u0435\u0434\u0438\u0442\u0435\u043b\u044c\u043d\u043e, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u0447\u0435\u0441\u0442\u043d\u0435\u0435 \u0441\u0447\u0438\u0442\u0430\u0442\u044c \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u0435 \u0445\u043e\u0440\u043e\u0448\u0435\u0439 \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u043e\u0439 \u0437\u0440\u0438\u0442\u0435\u043b\u044c\u043d\u043e\u0433\u043e \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f, \u0430 \u043d\u0435 \u0433\u0430\u0440\u0430\u043d\u0442\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u044b\u043c \u0430\u043f\u0433\u0440\u0435\u0439\u0434\u043e\u043c \u0434\u043b\u044f \u0440\u0435\u0430\u043b\u044c\u043d\u043e\u0439 \u0436\u0438\u0437\u043d\u0438."],["\u041b\u0443\u0447\u0448\u0435 \u0438\u0441\u043a\u0430\u0442\u044c \u043c\u0435\u0434\u043b\u0435\u043d\u043d\u043e \u0438 \u0430\u043a\u043a\u0443\u0440\u0430\u0442\u043d\u043e \u0438\u043b\u0438 \u0433\u043d\u0430\u0442\u044c \u043d\u0430 \u043c\u0430\u043a\u0441\u0438\u043c\u0430\u043b\u044c\u043d\u043e\u0439 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u0438?","\u0421\u043d\u0430\u0447\u0430\u043b\u0430 \u043d\u0430\u0440\u0430\u0431\u043e\u0442\u0430\u0439\u0442\u0435 \u0442\u043e\u0447\u043d\u043e\u0441\u0442\u044c, \u043f\u043e\u0442\u043e\u043c \u0434\u043e\u0431\u0430\u0432\u043b\u044f\u0439\u0442\u0435 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c. \u0411\u044b\u0441\u0442\u0440\u044b\u0439 \u043e\u0441\u043c\u043e\u0442\u0440, \u043f\u043e\u043b\u043d\u044b\u0439 \u043f\u0440\u043e\u043c\u0430\u0445\u043e\u0432, \u0437\u0430\u043a\u0440\u0435\u043f\u043b\u044f\u0435\u0442 \u043f\u043b\u043e\u0445\u0438\u0435 \u043f\u0440\u0438\u0432\u044b\u0447\u043a\u0438; \u0434\u0435\u0440\u0436\u0438\u0442\u0435 \u0440\u043e\u0432\u043d\u044b\u0439, \u0443\u043f\u043e\u0440\u044f\u0434\u043e\u0447\u0435\u043d\u043d\u044b\u0439 \u043c\u0430\u0440\u0448\u0440\u0443\u0442 \u0432\u0437\u0433\u043b\u044f\u0434\u0430, \u0438 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u044c \u0441\u0430\u043c\u0430 \u0432\u044b\u0440\u0430\u0441\u0442\u0435\u0442, \u043a\u043e\u0433\u0434\u0430 \u0433\u043b\u0430\u0437\u0430 \u043d\u0430\u0443\u0447\u0430\u0442\u0441\u044f, \u043a\u0443\u0434\u0430 \u0441\u043c\u043e\u0442\u0440\u0435\u0442\u044c."]],variants:"\u0421\u0440\u0435\u0434\u0438 \u0447\u0430\u0441\u0442\u044b\u0445 \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u043e\u0432 \u0435\u0441\u0442\u044c \u043f\u043e\u0438\u0441\u043a \u043f\u043e \u043f\u0440\u0438\u0437\u043d\u0430\u043a\u0443, \u0433\u0434\u0435 \u0446\u0435\u043b\u044c \u043e\u0442\u043b\u0438\u0447\u0430\u0435\u0442\u0441\u044f \u043e\u0434\u043d\u0438\u043c \u044f\u0432\u043d\u044b\u043c \u0441\u0432\u043e\u0439\u0441\u0442\u0432\u043e\u043c \u0438 \u0431\u0443\u0434\u0442\u043e \u0441\u0430\u043c\u0430 \u0431\u0440\u043e\u0441\u0430\u0435\u0442\u0441\u044f \u0432 \u0433\u043b\u0430\u0437\u0430, \u0438 \u043f\u043e\u0438\u0441\u043a \u043f\u043e \u0441\u043e\u0447\u0435\u0442\u0430\u043d\u0438\u044e, \u0433\u0434\u0435 \u043e\u043d\u0430 \u0434\u0435\u043b\u0438\u0442 \u043f\u0440\u0438\u0437\u043d\u0430\u043a\u0438 \u0441 \u043e\u0442\u0432\u043b\u0435\u043a\u0430\u044e\u0449\u0438\u043c\u0438 \u0438 \u0435\u0451 \u043f\u0440\u0438\u0445\u043e\u0434\u0438\u0442\u0441\u044f \u0432\u044b\u0438\u0441\u043a\u0438\u0432\u0430\u0442\u044c \u043f\u043e \u043e\u0434\u043d\u043e\u043c\u0443. \u0421\u043b\u043e\u0436\u043d\u043e\u0441\u0442\u044c \u0440\u0435\u0433\u0443\u043b\u0438\u0440\u0443\u044e\u0442, \u0434\u043e\u0431\u0430\u0432\u043b\u044f\u044f \u043e\u0442\u0432\u043b\u0435\u043a\u0430\u044e\u0449\u0438\u0435 \u043e\u0431\u044a\u0435\u043a\u0442\u044b, \u0443\u043c\u0435\u043d\u044c\u0448\u0430\u044f \u0440\u0430\u0437\u043b\u0438\u0447\u0438\u044f, \u0432\u0432\u043e\u0434\u044f \u043e\u0433\u0440\u0430\u043d\u0438\u0447\u0435\u043d\u0438\u0435 \u043f\u043e \u0432\u0440\u0435\u043c\u0435\u043d\u0438 \u0438\u043b\u0438 \u043f\u0440\u044f\u0447\u0430 \u0446\u0435\u043b\u044c \u0441\u0440\u0435\u0434\u0438 \u0434\u0432\u043e\u0439\u043d\u0438\u043a\u043e\u0432, \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u043c\u0435\u043d\u044f\u044e\u0442\u0441\u044f \u043a\u0430\u0436\u0434\u044b\u0439 \u0440\u0430\u0443\u043d\u0434."},en:{about:"Visual Search shows you a field of items and asks you to find one specific target among the distractors as fast as you can, then tap it. Sometimes the target stands out by a single feature, like the one red dot among blue ones; sometimes it shares every feature with the distractors and only the combination is unique, so you have to inspect items one by one.",benefit:"It trains selective visual attention and the efficiency with which you scan a scene: filtering out irrelevant clutter, holding the target's defining features in mind, and deciding quickly whether each item matches. With practice your search becomes faster and your useful field of view, the area you can take in around your point of fixation, tends to widen.",history:"Visual search as a laboratory method took shape in the early 1960s with Ulric Neisser, who timed how people scanned columns of letters for a target. It became central to attention research in 1980, when a single study used it to test a major theory, and from there it spread into ergonomics, radiology and airport screening, and eventually into consumer brain-training apps.",creator:"There is no single inventor of the exercise itself. The search paradigm is usually credited to Ulric Neisser in the early 1960s, and it was made famous by Anne Treisman and Garry Gelade in their 1980 paper A Feature-Integration Theory of Attention, which used visual search experiments to argue that simple features are found in parallel while feature combinations must be searched one item at a time.",methods:"Do not stare at one spot and wait; let your gaze sweep the field in a steady, systematic pattern rather than jumping around at random. Fix the target's defining feature clearly in mind before you start, and on conjunction trials, where nothing pops out, resist the urge to rush and accept that you must check items in turn. Push gently for speed only once your accuracy is reliable, since careless misses cost more than a slightly slower scan.",duration:"Short, frequent sessions work best: roughly 5 to 10 minutes at a time, a few times a week. Stop when your reaction times start drifting upward or your error rate climbs, because a tired search is sloppy search and you stop learning the right habits.",research:"Evidence is strongest for exactly what you would expect: you get faster and more accurate at visual search itself, and related training has been shown to widen the useful field of view. The broader promises are much weaker. Speed-of-processing and useful-field-of-view training has some of the better real-world findings in the field, including effects on older drivers, but those results are debated and far-reaching claims about raising general intelligence or preventing cognitive decline remain largely unproven, so treat the grand promises with caution.",rec:"Keep your eyes near the centre and let attention do the work; resist the reflex to physically dart your gaze at every item, especially when nothing pops out.",faq:[["Why does the target sometimes pop out instantly and other times take ages to find?","When the target differs by a single basic feature, like colour or orientation, your visual system spots it almost in parallel, so it pops out. When it only differs by a combination of features shared with the distractors, you have to inspect items more or less one at a time, which is why it feels slow and effortful."],["Will this make me notice things faster in real life, like spotting a friend in a crowd?","You will reliably get better at this kind of search task, and your scanning may become a bit more efficient. Whether that carries over to everyday situations is uncertain and not strongly proven, so it is honest to treat it as good training for visual attention rather than a guaranteed real-world upgrade."],["Is it better to scan slowly and carefully or to go as fast as possible?","Build accuracy first, then add speed. A fast scan full of misses teaches bad habits; aim for a steady, systematic sweep and let your speed rise naturally as your eyes learn where to look."]],variants:"Common variations include feature search, where the target differs by one obvious property and seems to jump out, and conjunction search, where it shares features with distractors and must be hunted item by item. Difficulty can be scaled by adding distractors, shrinking the differences, setting a time limit, or hiding the target among look-alikes that change every round."},es:{about:"Visual Search te muestra un campo de elementos y te pide que encuentres un objetivo concreto entre los distractores lo m\xe1s r\xe1pido posible, y luego lo toques. A veces el objetivo destaca por un solo rasgo, como el \xfanico punto rojo entre puntos azules; a veces comparte todos los rasgos con los distractores y solo la combinaci\xf3n es \xfanica, as\xed que tienes que inspeccionar los elementos uno a uno.",benefit:"Entrena la atenci\xf3n visual selectiva y la eficiencia con la que recorres una escena: filtrar el desorden irrelevante, mantener en mente los rasgos que definen al objetivo y decidir con rapidez si cada elemento coincide. Con la pr\xe1ctica tu b\xfasqueda se vuelve m\xe1s r\xe1pida y tu campo visual \xfatil, la zona que abarcas alrededor de tu punto de fijaci\xf3n, tiende a ampliarse.",history:"La b\xfasqueda visual como m\xe9todo de laboratorio tom\xf3 forma a comienzos de los a\xf1os 60 con Ulric Neisser, que cronometr\xf3 c\xf3mo la gente recorr\xeda columnas de letras buscando un objetivo. Pas\xf3 a ser central en la investigaci\xf3n sobre atenci\xf3n en 1980, cuando un solo estudio la us\xf3 para poner a prueba una teor\xeda importante, y de ah\xed se extendi\xf3 a la ergonom\xeda, la radiolog\xeda y los controles de seguridad de aeropuerto, y finalmente a las aplicaciones de entrenamiento mental.",creator:"No hay un \xfanico inventor del ejercicio en s\xed. El paradigma de b\xfasqueda suele atribuirse a Ulric Neisser a comienzos de los a\xf1os 60, y lo hicieron famoso Anne Treisman y Garry Gelade en su art\xedculo de 1980 A Feature-Integration Theory of Attention, que us\xf3 experimentos de b\xfasqueda visual para argumentar que los rasgos simples se encuentran en paralelo, mientras que las combinaciones de rasgos deben buscarse elemento por elemento.",methods:"No te quedes mirando un solo punto a la espera; deja que tu mirada barra el campo con un patr\xf3n estable y sistem\xe1tico en lugar de saltar de un lado a otro al azar. Fija con claridad en tu mente el rasgo que define al objetivo antes de empezar, y en los ensayos de conjunci\xf3n, donde nada resalta, resiste el impulso de apresurarte y acepta que debes revisar los elementos por turnos. Empuja con suavidad por la velocidad solo cuando tu precisi\xf3n sea fiable, ya que los fallos por descuido cuestan m\xe1s que un barrido algo m\xe1s lento.",duration:"Las sesiones cortas y frecuentes funcionan mejor: en torno a 5 o 10 minutos cada vez, unas pocas veces por semana. Para cuando tus tiempos de reacci\xf3n empiecen a subir o tu tasa de errores trepe, porque una b\xfasqueda cansada es una b\xfasqueda descuidada y dejas de aprender los h\xe1bitos correctos.",research:"La evidencia es m\xe1s fuerte para justo lo que cabr\xeda esperar: mejoras en velocidad y precisi\xf3n en la propia b\xfasqueda visual, y se ha demostrado que un entrenamiento af\xedn ampl\xeda el campo visual \xfatil. Las promesas m\xe1s amplias son mucho m\xe1s d\xe9biles. El entrenamiento de la velocidad de procesamiento y del campo visual \xfatil tiene algunos de los mejores hallazgos del campo en el mundo real, incluidos efectos en conductores mayores, pero esos resultados est\xe1n en discusi\xf3n y las afirmaciones de gran alcance sobre elevar la inteligencia general o prevenir el declive cognitivo siguen en gran medida sin demostrar, as\xed que toma las grandes promesas con cautela.",rec:"Mant\xe9n la vista cerca del centro y deja que la atenci\xf3n haga el trabajo; resiste el reflejo de lanzar f\xedsicamente la mirada a cada elemento, sobre todo cuando nada resalta.",faq:[["\xbfPor qu\xe9 a veces el objetivo salta a la vista al instante y otras veces tardo un siglo en encontrarlo?","Cuando el objetivo se diferencia por un \xfanico rasgo b\xe1sico, como el color o la orientaci\xf3n, tu sistema visual lo detecta casi en paralelo, as\xed que salta a la vista. Cuando solo se diferencia por una combinaci\xf3n de rasgos compartidos con los distractores, tienes que inspeccionar los elementos m\xe1s o menos uno a uno, y por eso se siente lento y costoso."],["\xbfEsto me har\xe1 notar las cosas m\xe1s r\xe1pido en la vida real, como localizar a un amigo entre la multitud?","Mejorar\xe1s de forma fiable en este tipo de tarea de b\xfasqueda, y tu barrido puede volverse algo m\xe1s eficiente. Que eso se traslade a situaciones cotidianas es incierto y no est\xe1 s\xf3lidamente demostrado, as\xed que es honesto tomarlo como buen entrenamiento para la atenci\xf3n visual y no como una mejora garantizada en el mundo real."],["\xbfEs mejor barrer despacio y con cuidado o ir lo m\xe1s r\xe1pido posible?","Construye primero la precisi\xf3n y luego a\xf1ade velocidad. Un barrido r\xe1pido lleno de fallos ense\xf1a malos h\xe1bitos; busca un recorrido estable y sistem\xe1tico y deja que tu velocidad suba de forma natural a medida que tus ojos aprenden d\xf3nde mirar."]],variants:"Las variantes habituales incluyen la b\xfasqueda por rasgo, donde el objetivo se diferencia por una propiedad evidente y parece saltar a la vista, y la b\xfasqueda por conjunci\xf3n, donde comparte rasgos con los distractores y hay que cazarlo elemento por elemento. La dificultad puede escalarse a\xf1adiendo distractores, reduciendo las diferencias, poniendo un l\xedmite de tiempo o escondiendo el objetivo entre parecidos que cambian en cada ronda."},de:{about:"Visual Search zeigt dir ein Feld von Elementen und bittet dich, ein bestimmtes Ziel unter den Ablenkern so schnell wie m\xf6glich zu finden und es dann anzutippen. Manchmal sticht das Ziel durch ein einzelnes Merkmal hervor, etwa der eine rote Punkt unter blauen; manchmal teilt es jedes Merkmal mit den Ablenkern und nur die Kombination ist einzigartig, sodass du die Elemente eines nach dem anderen pr\xfcfen musst.",benefit:"Sie trainiert die selektive visuelle Aufmerksamkeit und die Effizienz, mit der du eine Szene absuchst: irrelevantes Durcheinander auszufiltern, die kennzeichnenden Merkmale des Ziels im Kopf zu behalten und schnell zu entscheiden, ob jedes Element passt. Mit \xdcbung wird deine Suche schneller, und dein nutzbares Blickfeld, der Bereich, den du rund um deinen Fixationspunkt erfassen kannst, neigt dazu, sich zu weiten.",history:"Die visuelle Suche als Labormethode nahm Anfang der 1960er Jahre mit Ulric Neisser Gestalt an, der ma\xdf, wie schnell Menschen Spalten von Buchstaben nach einem Ziel absuchten. Sie r\xfcckte 1980 ins Zentrum der Aufmerksamkeitsforschung, als eine einzelne Studie sie nutzte, um eine bedeutende Theorie zu pr\xfcfen, und von dort breitete sie sich in Ergonomie, Radiologie und Flughafenkontrolle aus und schlie\xdflich in Gehirntraining-Apps f\xfcr Verbraucher.",creator:"Es gibt keinen einzelnen Erfinder der \xdcbung selbst. Das Suchparadigma wird gew\xf6hnlich Ulric Neisser zu Beginn der 1960er Jahre zugeschrieben, und ber\xfchmt wurde es durch Anne Treisman und Garry Gelade in ihrem Aufsatz von 1980, A Feature-Integration Theory of Attention, der mit Experimenten zur visuellen Suche argumentierte, dass einfache Merkmale parallel gefunden werden, w\xe4hrend Merkmalskombinationen Element f\xfcr Element abgesucht werden m\xfcssen.",methods:"Starre nicht auf einen Fleck und warte; lass deinen Blick das Feld in einem gleichm\xe4\xdfigen, systematischen Muster \xfcberstreichen, statt willk\xfcrlich umherzuspringen. Pr\xe4ge dir das kennzeichnende Merkmal des Ziels klar ein, bevor du beginnst, und widersteh bei Konjunktionsdurchg\xe4ngen, wo nichts hervorspringt, dem Drang zu hetzen und akzeptiere, dass du die Elemente der Reihe nach pr\xfcfen musst. Treibe das Tempo erst dann sanft voran, wenn deine Genauigkeit verl\xe4sslich ist, denn unachtsame Fehlgriffe kosten mehr als ein etwas langsameres Absuchen.",duration:"Kurze, h\xe4ufige Sitzungen funktionieren am besten: ungef\xe4hr 5 bis 10 Minuten am St\xfcck, ein paar Mal pro Woche. H\xf6r auf, sobald deine Reaktionszeiten nach oben zu driften beginnen oder deine Fehlerquote steigt, denn eine m\xfcde Suche ist eine schludrige Suche, und du lernst dann nicht mehr die richtigen Gewohnheiten.",research:"Die Evidenz ist genau f\xfcr das am st\xe4rksten, was man erwarten w\xfcrde: Du wirst bei der visuellen Suche selbst schneller und genauer, und f\xfcr verwandtes Training wurde gezeigt, dass es das nutzbare Blickfeld weitet. Die breiteren Versprechen sind viel schw\xe4cher. Training der Verarbeitungsgeschwindigkeit und des nutzbaren Blickfelds geh\xf6rt zu den besseren realen Befunden des Feldes, einschlie\xdflich Effekten bei \xe4lteren Autofahrern, doch diese Ergebnisse sind umstritten, und weitreichende Behauptungen \xfcber das Heben der allgemeinen Intelligenz oder das Verhindern kognitiven Abbaus bleiben weitgehend unbewiesen, also begegne den gro\xdfen Versprechen mit Vorsicht.",rec:"Halte deine Augen nahe der Mitte und lass die Aufmerksamkeit die Arbeit machen; widersteh dem Reflex, deinen Blick k\xf6rperlich zu jedem Element zucken zu lassen, besonders wenn nichts hervorspringt.",faq:[["Warum springt das Ziel manchmal sofort hervor und braucht ein andermal ewig, um gefunden zu werden?","Wenn sich das Ziel durch ein einzelnes Grundmerkmal unterscheidet, etwa Farbe oder Ausrichtung, erfasst dein visuelles System es nahezu parallel, sodass es hervorspringt. Wenn es sich nur durch eine Kombination von Merkmalen unterscheidet, die es mit den Ablenkern teilt, musst du die Elemente mehr oder weniger einzeln pr\xfcfen, weshalb es sich langsam und m\xfchsam anf\xfchlt."],["Werde ich dadurch im echten Leben Dinge schneller bemerken, etwa einen Freund in einer Menge entdecken?","Du wirst in dieser Art von Suchaufgabe zuverl\xe4ssig besser, und dein Absuchen wird vielleicht etwas effizienter. Ob sich das auf Alltagssituationen \xfcbertr\xe4gt, ist ungewiss und nicht klar belegt, also ist es ehrlich, es als gutes Training f\xfcr die visuelle Aufmerksamkeit zu betrachten statt als garantiertes Upgrade f\xfcr die reale Welt."],["Ist es besser, langsam und sorgf\xe4ltig abzusuchen oder so schnell wie m\xf6glich?","Baue zuerst Genauigkeit auf, f\xfcge dann Tempo hinzu. Ein schnelles Absuchen voller Fehlgriffe lehrt schlechte Gewohnheiten; strebe ein gleichm\xe4\xdfiges, systematisches \xdcberstreichen an und lass dein Tempo nat\xfcrlich steigen, w\xe4hrend deine Augen lernen, wo sie hinschauen m\xfcssen."]],variants:"\xdcbliche Abwandlungen sind die Merkmalssuche, bei der sich das Ziel durch eine offensichtliche Eigenschaft unterscheidet und herauszuspringen scheint, und die Konjunktionssuche, bei der es Merkmale mit den Ablenkern teilt und Element f\xfcr Element gejagt werden muss. Der Schwierigkeitsgrad l\xe4sst sich skalieren, indem man Ablenker hinzuf\xfcgt, die Unterschiede verkleinert, ein Zeitlimit setzt oder das Ziel unter \xe4hnlich aussehenden Elementen versteckt, die in jeder Runde wechseln."},pt:{about:"Visual Search mostra a voc\xea um campo de itens e pede que encontre um alvo espec\xedfico entre os distratores o mais r\xe1pido poss\xedvel, e ent\xe3o o toque. \xc0s vezes o alvo se destaca por uma \xfanica caracter\xedstica, como o \xfanico ponto vermelho entre os azuis; \xe0s vezes ele compartilha todas as caracter\xedsticas com os distratores e s\xf3 a combina\xe7\xe3o \xe9 \xfanica, ent\xe3o voc\xea precisa inspecionar os itens um a um.",benefit:"Treina a aten\xe7\xe3o visual seletiva e a efici\xeancia com que voc\xea varre uma cena: filtrar a desordem irrelevante, manter em mente as caracter\xedsticas que definem o alvo e decidir rapidamente se cada item corresponde. Com a pr\xe1tica sua busca fica mais r\xe1pida e seu campo de vis\xe3o \xfatil, a \xe1rea que voc\xea consegue absorver ao redor do ponto de fixa\xe7\xe3o, tende a se ampliar.",history:"A busca visual como m\xe9todo de laborat\xf3rio tomou forma no in\xedcio dos anos 1960 com Ulric Neisser, que cronometrou como as pessoas varriam colunas de letras em busca de um alvo. Tornou-se central para a pesquisa sobre aten\xe7\xe3o em 1980, quando um \xfanico estudo a usou para testar uma teoria importante, e dali se espalhou para a ergonomia, a radiologia e a inspe\xe7\xe3o de aeroportos, e por fim para os aplicativos comerciais de treino cerebral.",creator:"N\xe3o h\xe1 um \xfanico inventor do exerc\xedcio em si. O paradigma de busca costuma ser creditado a Ulric Neisser no in\xedcio dos anos 1960, e foi tornado famoso por Anne Treisman e Garry Gelade em seu artigo de 1980, A Feature-Integration Theory of Attention, que usou experimentos de busca visual para argumentar que caracter\xedsticas simples s\xe3o encontradas em paralelo, ao passo que combina\xe7\xf5es de caracter\xedsticas precisam ser buscadas um item de cada vez.",methods:"N\xe3o fixe o olhar em um \xfanico ponto e espere; deixe seu olhar varrer o campo num padr\xe3o est\xe1vel e sistem\xe1tico, em vez de pular ao acaso. Fixe claramente em mente a caracter\xedstica que define o alvo antes de come\xe7ar, e nas tentativas de conjun\xe7\xe3o, em que nada salta aos olhos, resista \xe0 vontade de apressar e aceite que precisa checar os itens por vez. Force suavemente por velocidade apenas quando sua precis\xe3o estiver confi\xe1vel, j\xe1 que erros por descuido custam mais do que uma varredura um pouco mais lenta.",duration:"Sess\xf5es curtas e frequentes funcionam melhor: cerca de 5 a 10 minutos por vez, algumas vezes por semana. Pare quando seus tempos de rea\xe7\xe3o come\xe7arem a subir ou sua taxa de erro escalar, porque uma busca cansada \xe9 uma busca desleixada e voc\xea deixa de aprender os h\xe1bitos certos.",research:"A evid\xeancia \xe9 mais forte para exatamente o que se esperaria: voc\xea fica mais r\xe1pido e mais preciso na pr\xf3pria busca visual, e treinos relacionados demonstraram ampliar o campo de vis\xe3o \xfatil. As promessas mais amplas s\xe3o bem mais fracas. O treino de velocidade de processamento e de campo de vis\xe3o \xfatil tem alguns dos melhores achados do mundo real da \xe1rea, incluindo efeitos sobre motoristas mais velhos, mas esses resultados s\xe3o debatidos e afirma\xe7\xf5es de longo alcance sobre elevar a intelig\xeancia geral ou prevenir o decl\xednio cognitivo permanecem em grande parte n\xe3o comprovadas, ent\xe3o trate as promessas grandiosas com cautela.",rec:"Mantenha os olhos perto do centro e deixe a aten\xe7\xe3o fazer o trabalho; resista ao reflexo de disparar o olhar fisicamente em cada item, especialmente quando nada salta aos olhos.",faq:[["Por que \xe0s vezes o alvo salta aos olhos na hora e outras vezes leva uma eternidade para ser achado?","Quando o alvo difere por uma \xfanica caracter\xedstica b\xe1sica, como cor ou orienta\xe7\xe3o, seu sistema visual o detecta quase em paralelo, ent\xe3o ele salta aos olhos. Quando ele s\xf3 difere por uma combina\xe7\xe3o de caracter\xedsticas compartilhadas com os distratores, voc\xea precisa inspecionar os itens mais ou menos um de cada vez, e \xe9 por isso que parece lento e trabalhoso."],["Isto vai me fazer notar coisas mais r\xe1pido na vida real, como achar um amigo numa multid\xe3o?","Voc\xea vai confiavelmente melhorar neste tipo de tarefa de busca, e sua varredura pode ficar um pouco mais eficiente. Se isso se transfere para situa\xe7\xf5es do dia a dia \xe9 incerto e n\xe3o est\xe1 fortemente comprovado, ent\xe3o \xe9 honesto encarar como um bom treino para a aten\xe7\xe3o visual, e n\xe3o como uma melhoria garantida no mundo real."],["\xc9 melhor varrer devagar e com cuidado ou ir o mais r\xe1pido poss\xedvel?","Construa primeiro a precis\xe3o, depois acrescente velocidade. Uma varredura r\xe1pida cheia de erros ensina maus h\xe1bitos; busque uma varredura est\xe1vel e sistem\xe1tica e deixe sua velocidade subir naturalmente conforme seus olhos aprendem onde olhar."]],variants:"Varia\xe7\xf5es comuns incluem a busca por caracter\xedstica, em que o alvo difere por uma propriedade \xf3bvia e parece saltar aos olhos, e a busca por conjun\xe7\xe3o, em que ele compartilha caracter\xedsticas com os distratores e precisa ser ca\xe7ado item por item. A dificuldade pode ser escalada acrescentando distratores, encolhendo as diferen\xe7as, impondo um limite de tempo ou escondendo o alvo entre s\xf3sias que mudam a cada rodada."},hi:{about:"Visual Search \u0906\u092a\u0915\u094b \u091a\u0940\u091c\u093c\u094b\u0902 \u0915\u093e \u090f\u0915 \u092e\u0948\u0926\u093e\u0928 \u0926\u093f\u0916\u093e\u0924\u093e \u0939\u0948 \u0914\u0930 \u0915\u0939\u0924\u093e \u0939\u0948 \u0915\u093f \u092d\u091f\u0915\u093e\u0928\u0947 \u0935\u093e\u0932\u094b\u0902 (\u0921\u093f\u0938\u094d\u091f\u094d\u0930\u0948\u0915\u094d\u091f\u0930) \u0915\u0947 \u092c\u0940\u091a \u090f\u0915 \u0916\u093e\u0938 \u0932\u0915\u094d\u0937\u094d\u092f \u0915\u094b \u091c\u093f\u0924\u0928\u0940 \u091c\u0932\u094d\u0926\u0940 \u0939\u094b \u0938\u0915\u0947 \u0922\u0942\u0901\u0922\u093f\u090f, \u092b\u093f\u0930 \u0909\u0938 \u092a\u0930 \u091f\u0948\u092a \u0915\u0940\u091c\u093f\u090f\u0964 \u0915\u092d\u0940 \u0932\u0915\u094d\u0937\u094d\u092f \u0915\u093f\u0938\u0940 \u090f\u0915 \u0939\u0940 \u0935\u093f\u0936\u0947\u0937\u0924\u093e \u0938\u0947 \u0905\u0932\u0917 \u0926\u093f\u0916\u0924\u093e \u0939\u0948, \u091c\u0948\u0938\u0947 \u0928\u0940\u0932\u0947 \u092c\u093f\u0902\u0926\u0941\u0913\u0902 \u0915\u0947 \u092c\u0940\u091a \u0935\u0939 \u090f\u0915 \u0932\u093e\u0932 \u092c\u093f\u0902\u0926\u0941; \u0915\u092d\u0940 \u092f\u0939 \u092d\u091f\u0915\u093e\u0928\u0947 \u0935\u093e\u0932\u094b\u0902 \u0915\u0947 \u0938\u093e\u0925 \u0939\u0930 \u0935\u093f\u0936\u0947\u0937\u0924\u093e \u0938\u093e\u091d\u093e \u0915\u0930\u0924\u093e \u0939\u0948 \u0914\u0930 \u0938\u093f\u0930\u094d\u092b\u093c \u0909\u0928\u0915\u093e \u0938\u0902\u092f\u094b\u091c\u0928 \u0939\u0940 \u0905\u0928\u0942\u0920\u093e \u0939\u094b\u0924\u093e \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0906\u092a\u0915\u094b \u091a\u0940\u091c\u093c\u094b\u0902 \u0915\u094b \u090f\u0915-\u090f\u0915 \u0915\u0930\u0915\u0947 \u091c\u093e\u0901\u091a\u0928\u093e \u092a\u0921\u093c\u0924\u093e \u0939\u0948\u0964",benefit:"\u092f\u0939 \u091a\u092f\u0928\u093e\u0924\u094d\u092e\u0915 \u0926\u0943\u0936\u094d\u092f \u0927\u094d\u092f\u093e\u0928 (\u0938\u0947\u0932\u0947\u0915\u094d\u091f\u093f\u0935 \u0935\u093f\u091c\u093c\u0941\u0905\u0932 \u0905\u091f\u0947\u0902\u0936\u0928) \u0914\u0930 \u0909\u0938 \u0926\u0915\u094d\u0937\u0924\u093e \u0915\u093e \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0930\u093e\u0924\u093e \u0939\u0948 \u091c\u093f\u0938\u0938\u0947 \u0906\u092a \u0915\u093f\u0938\u0940 \u0926\u0943\u0936\u094d\u092f \u0915\u094b \u091b\u093e\u0928\u0924\u0947 \u0939\u0948\u0902: \u0917\u093c\u0948\u0930-\u091c\u093c\u0930\u0942\u0930\u0940 \u0905\u0935\u094d\u092f\u0935\u0938\u094d\u0925\u093e \u0915\u094b \u091b\u093e\u0901\u091f\u0928\u093e, \u0932\u0915\u094d\u0937\u094d\u092f \u0915\u0940 \u092a\u0930\u093f\u092d\u093e\u0937\u0915 \u0935\u093f\u0936\u0947\u0937\u0924\u093e\u0913\u0902 \u0915\u094b \u0926\u093f\u092e\u093e\u0917 \u092e\u0947\u0902 \u0925\u093e\u092e\u0947 \u0930\u0916\u0928\u093e, \u0914\u0930 \u092b\u091f\u093e\u092b\u091f \u0924\u092f \u0915\u0930\u0928\u093e \u0915\u093f \u0939\u0930 \u091a\u0940\u091c\u093c \u092e\u0947\u0932 \u0916\u093e\u0924\u0940 \u0939\u0948 \u092f\u093e \u0928\u0939\u0940\u0902\u0964 \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0947 \u0938\u093e\u0925 \u0906\u092a\u0915\u0940 \u0916\u094b\u091c \u0924\u0947\u091c\u093c \u0939\u094b \u091c\u093e\u0924\u0940 \u0939\u0948 \u0914\u0930 \u0906\u092a\u0915\u093e \u0909\u092a\u092f\u094b\u0917\u0940 \u0926\u0943\u0937\u094d\u091f\u093f-\u0915\u094d\u0937\u0947\u0924\u094d\u0930 (\u092f\u0942\u091c\u093c\u092b\u093c\u0941\u0932 \u092b\u093c\u0940\u0932\u094d\u0921 \u0911\u092b\u093c \u0935\u094d\u092f\u0942), \u092f\u093e\u0928\u0940 \u0906\u092a \u0905\u092a\u0928\u0947 \u091f\u0915\u091f\u0915\u0940-\u092c\u093f\u0902\u0926\u0941 \u0915\u0947 \u0907\u0930\u094d\u0926-\u0917\u093f\u0930\u094d\u0926 \u091c\u093f\u0924\u0928\u093e \u0907\u0932\u093e\u0915\u093e \u090f\u0915 \u0938\u093e\u0925 \u0938\u092e\u0947\u091f \u0938\u0915\u0924\u0947 \u0939\u0948\u0902, \u091a\u094c\u0921\u093c\u093e \u0939\u094b\u0924\u093e \u091c\u093e\u0924\u093e \u0939\u0948\u0964",history:"\u092a\u094d\u0930\u092f\u094b\u0917\u0936\u093e\u0932\u093e \u0935\u093f\u0927\u093f \u0915\u0947 \u0930\u0942\u092a \u092e\u0947\u0902 \u0926\u0943\u0936\u094d\u092f \u0916\u094b\u091c \u0928\u0947 1960 \u0915\u0947 \u0926\u0936\u0915 \u0915\u0940 \u0936\u0941\u0930\u0941\u0906\u0924 \u092e\u0947\u0902 Ulric Neisser \u0915\u0947 \u0938\u093e\u0925 \u0906\u0915\u093e\u0930 \u0932\u093f\u092f\u093e, \u091c\u093f\u0928\u094d\u0939\u094b\u0902\u0928\u0947 \u0928\u093e\u092a\u093e \u0915\u093f \u0932\u094b\u0917 \u0915\u093f\u0938\u0940 \u0932\u0915\u094d\u0937\u094d\u092f \u0915\u0947 \u0932\u093f\u090f \u0905\u0915\u094d\u0937\u0930\u094b\u0902 \u0915\u0947 \u0938\u094d\u0924\u0902\u092d\u094b\u0902 \u0915\u094b \u0915\u0948\u0938\u0947 \u091b\u093e\u0928\u0924\u0947 \u0939\u0948\u0902\u0964 \u092f\u0939 1980 \u092e\u0947\u0902 \u0927\u094d\u092f\u093e\u0928-\u0936\u094b\u0927 \u0915\u0947 \u0915\u0947\u0902\u0926\u094d\u0930 \u092e\u0947\u0902 \u0906 \u0917\u092f\u093e, \u091c\u092c \u090f\u0915 \u0905\u0915\u0947\u0932\u0947 \u0905\u0927\u094d\u092f\u092f\u0928 \u0928\u0947 \u090f\u0915 \u092c\u0921\u093c\u0947 \u0938\u093f\u0926\u094d\u0927\u093e\u0902\u0924 \u0915\u094b \u092a\u0930\u0916\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0907\u0938\u0915\u093e \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0915\u093f\u092f\u093e, \u0914\u0930 \u0935\u0939\u093e\u0901 \u0938\u0947 \u092f\u0939 \u090f\u0930\u094d\u0917\u094b\u0928\u0949\u092e\u093f\u0915\u094d\u0938, \u0930\u0947\u0921\u093f\u092f\u094b\u0932\u0949\u091c\u0940 \u0914\u0930 \u0939\u0935\u093e\u0908-\u0905\u0921\u094d\u0921\u0947 \u0915\u0940 \u091c\u093e\u0901\u091a \u092e\u0947\u0902 \u092b\u0948\u0932\u093e, \u0914\u0930 \u0906\u0916\u093c\u093f\u0930\u0915\u093e\u0930 \u0909\u092a\u092d\u094b\u0915\u094d\u0924\u093e \u0926\u093f\u092e\u093e\u0917\u0940-\u0915\u0938\u0930\u0924 \u0910\u092a\u094d\u0938 \u092e\u0947\u0902 \u092a\u0939\u0941\u0901\u091a\u093e\u0964",creator:"\u0916\u0941\u0926 \u0907\u0938 \u0915\u0938\u0930\u0924 \u0915\u093e \u0915\u094b\u0908 \u090f\u0915\u092e\u093e\u0924\u094d\u0930 \u0906\u0935\u093f\u0937\u094d\u0915\u093e\u0930\u0915 \u0928\u0939\u0940\u0902 \u0939\u0948\u0964 \u0916\u094b\u091c \u092a\u094d\u0930\u0924\u093f\u092e\u093e\u0928 (\u092a\u0948\u0930\u093e\u0921\u093e\u0907\u092e) \u0915\u093e \u0936\u094d\u0930\u0947\u092f \u0906\u092e\u0924\u094c\u0930 \u092a\u0930 1960 \u0915\u0947 \u0926\u0936\u0915 \u0915\u0940 \u0936\u0941\u0930\u0941\u0906\u0924 \u092e\u0947\u0902 Ulric Neisser \u0915\u094b \u0926\u093f\u092f\u093e \u091c\u093e\u0924\u093e \u0939\u0948, \u0914\u0930 \u0907\u0938\u0947 \u092e\u0936\u0939\u0942\u0930 \u0915\u093f\u092f\u093e Anne Treisman \u0914\u0930 Garry Gelade \u0928\u0947 \u0905\u092a\u0928\u0947 1980 \u0915\u0947 \u092a\u0930\u094d\u091a\u0947 A Feature-Integration Theory of Attention \u092e\u0947\u0902, \u091c\u093f\u0938\u0928\u0947 \u0926\u0943\u0936\u094d\u092f-\u0916\u094b\u091c \u092a\u094d\u0930\u092f\u094b\u0917\u094b\u0902 \u0915\u0947 \u091c\u093c\u0930\u093f\u090f \u092f\u0939 \u0924\u0930\u094d\u0915 \u0926\u093f\u092f\u093e \u0915\u093f \u0938\u0930\u0932 \u0935\u093f\u0936\u0947\u0937\u0924\u093e\u090f\u0901 \u0938\u092e\u093e\u0928\u093e\u0902\u0924\u0930 (\u092a\u0948\u0930\u0932\u0932) \u0930\u0942\u092a \u0938\u0947 \u092e\u093f\u0932 \u091c\u093e\u0924\u0940 \u0939\u0948\u0902 \u091c\u092c\u0915\u093f \u0935\u093f\u0936\u0947\u0937\u0924\u093e\u0913\u0902 \u0915\u0947 \u0938\u0902\u092f\u094b\u091c\u0928\u094b\u0902 \u0915\u094b \u090f\u0915 \u092c\u093e\u0930 \u092e\u0947\u0902 \u090f\u0915 \u091a\u0940\u091c\u093c \u0915\u0930\u0915\u0947 \u0916\u094b\u091c\u0928\u093e \u092a\u0921\u093c\u0924\u093e \u0939\u0948\u0964",methods:"\u090f\u0915 \u0939\u0940 \u091c\u0917\u0939 \u0918\u0942\u0930\u0915\u0930 \u0907\u0902\u0924\u091c\u093c\u093e\u0930 \u092e\u0924 \u0915\u0940\u091c\u093f\u090f; \u0905\u092a\u0928\u0940 \u0928\u091c\u093c\u0930 \u0915\u094b \u092e\u0948\u0926\u093e\u0928 \u092a\u0930 \u092c\u0947\u0924\u0930\u0924\u0940\u092c \u0909\u091b\u0932\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u090f\u0915 \u0938\u094d\u0925\u093f\u0930, \u0935\u094d\u092f\u0935\u0938\u094d\u0925\u093f\u0924 \u092a\u0948\u091f\u0930\u094d\u0928 \u092e\u0947\u0902 \u092b\u093f\u0930\u093e\u0907\u090f\u0964 \u0936\u0941\u0930\u0942 \u0915\u0930\u0928\u0947 \u0938\u0947 \u092a\u0939\u0932\u0947 \u0932\u0915\u094d\u0937\u094d\u092f \u0915\u0940 \u092a\u0930\u093f\u092d\u093e\u0937\u0915 \u0935\u093f\u0936\u0947\u0937\u0924\u093e \u0915\u094b \u0938\u093e\u092b\u093c \u0926\u093f\u092e\u093e\u0917 \u092e\u0947\u0902 \u092c\u093f\u0920\u093e \u0932\u0940\u091c\u093f\u090f, \u0914\u0930 \u0938\u0902\u092f\u094b\u091c\u0928 (\u0915\u0902\u091c\u0902\u0915\u094d\u0936\u0928) \u0935\u093e\u0932\u0940 \u092c\u093e\u0930\u093f\u092f\u094b\u0902 \u092a\u0930, \u091c\u0939\u093e\u0901 \u0915\u0941\u091b \u092d\u0940 \u0909\u092d\u0930\u0915\u0930 \u0938\u093e\u092e\u0928\u0947 \u0928\u0939\u0940\u0902 \u0906\u0924\u093e, \u0939\u0921\u093c\u092c\u0921\u093c\u0940 \u0915\u0940 \u0907\u091a\u094d\u091b\u093e \u0915\u094b \u0930\u094b\u0915\u093f\u090f \u0914\u0930 \u092f\u0939 \u092e\u093e\u0928 \u0932\u0940\u091c\u093f\u090f \u0915\u093f \u091a\u0940\u091c\u093c\u094b\u0902 \u0915\u094b \u092c\u093e\u0930\u0940-\u092c\u093e\u0930\u0940 \u091c\u093e\u0901\u091a\u0928\u093e \u0939\u0940 \u092a\u0921\u093c\u0947\u0917\u093e\u0964 \u0917\u0924\u093f \u0915\u0947 \u0932\u093f\u090f \u0927\u0940\u0930\u0947 \u0938\u0947 \u0924\u092d\u0940 \u091c\u093c\u094b\u0930 \u0932\u0917\u093e\u0907\u090f \u091c\u092c \u0906\u092a\u0915\u0940 \u0938\u091f\u0940\u0915\u0924\u093e \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0939\u094b, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u0932\u093e\u092a\u0930\u0935\u093e\u0939 \u091a\u0942\u0915\u0947\u0902 \u090f\u0915 \u091c\u093c\u0930\u093e \u0927\u0940\u092e\u0940 \u091b\u093e\u0928\u092c\u0940\u0928 \u0938\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u092e\u0939\u0901\u0917\u0940 \u092a\u0921\u093c\u0924\u0940 \u0939\u0948\u0902\u0964",duration:"\u091b\u094b\u091f\u0947, \u092c\u093e\u0930-\u092c\u093e\u0930 \u0915\u0947 \u0938\u0924\u094d\u0930 \u0938\u092c\u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u0915\u093e\u092e \u0915\u0930\u0924\u0947 \u0939\u0948\u0902: \u090f\u0915 \u092c\u093e\u0930 \u092e\u0947\u0902 \u0915\u0930\u0940\u092c 5 \u0938\u0947 10 \u092e\u093f\u0928\u091f, \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u0915\u0941\u091b \u092c\u093e\u0930\u0964 \u091c\u092c \u0906\u092a\u0915\u0947 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0938\u092e\u092f \u090a\u092a\u0930 \u0916\u093f\u0938\u0915\u0928\u0947 \u0932\u0917\u0947\u0902 \u092f\u093e \u0906\u092a\u0915\u0940 \u0924\u094d\u0930\u0941\u091f\u093f-\u0926\u0930 \u091a\u0922\u093c\u0928\u0947 \u0932\u0917\u0947 \u0924\u094b \u0930\u0941\u0915 \u091c\u093e\u0907\u090f, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u0925\u0915\u0940 \u0939\u0941\u0908 \u0916\u094b\u091c \u0932\u093e\u092a\u0930\u0935\u093e\u0939 \u0916\u094b\u091c \u0939\u094b\u0924\u0940 \u0939\u0948 \u0914\u0930 \u0906\u092a \u0938\u0939\u0940 \u0906\u0926\u0924\u0947\u0902 \u0938\u0940\u0916\u0928\u093e \u092c\u0902\u0926 \u0915\u0930 \u0926\u0947\u0924\u0947 \u0939\u0948\u0902\u0964",research:"\u0938\u092c\u0938\u0947 \u092a\u0941\u0916\u093c\u094d\u0924\u093e \u0938\u092c\u0942\u0924 \u0920\u0940\u0915 \u0909\u0938\u0940 \u092c\u093e\u0924 \u0915\u093e \u0939\u0948 \u091c\u093f\u0938\u0915\u0940 \u0906\u092a \u0909\u092e\u094d\u092e\u0940\u0926 \u0915\u0930\u0947\u0902\u0917\u0947: \u0906\u092a \u0916\u0941\u0926 \u0926\u0943\u0936\u094d\u092f \u0916\u094b\u091c \u092e\u0947\u0902 \u0924\u0947\u091c\u093c \u0935 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0938\u091f\u0940\u0915 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u0907\u0938\u0938\u0947 \u091c\u0941\u0921\u093c\u0947 \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u0915\u094b \u0909\u092a\u092f\u094b\u0917\u0940 \u0926\u0943\u0937\u094d\u091f\u093f-\u0915\u094d\u0937\u0947\u0924\u094d\u0930 \u091a\u094c\u0921\u093c\u093e \u0915\u0930\u0924\u0947 \u0939\u0941\u090f \u0926\u093f\u0916\u093e\u092f\u093e \u0917\u092f\u093e \u0939\u0948\u0964 \u0935\u094d\u092f\u093e\u092a\u0915 \u0935\u093e\u0926\u0947 \u0915\u0939\u0940\u0902 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0915\u092e\u091c\u093c\u094b\u0930 \u0939\u0948\u0902\u0964 \u092a\u094d\u0930\u0938\u0902\u0938\u094d\u0915\u0930\u0923-\u0917\u0924\u093f \u0914\u0930 \u0909\u092a\u092f\u094b\u0917\u0940-\u0926\u0943\u0937\u094d\u091f\u093f-\u0915\u094d\u0937\u0947\u0924\u094d\u0930 \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u0915\u0947 \u092a\u093e\u0938 \u0907\u0938 \u0915\u094d\u0937\u0947\u0924\u094d\u0930 \u0915\u0947 \u0915\u0941\u091b \u092c\u0947\u0939\u0924\u0930 \u0905\u0938\u0932-\u0926\u0941\u0928\u093f\u092f\u093e \u0928\u0924\u0940\u091c\u0947 \u0939\u0948\u0902, \u091c\u093f\u0928\u092e\u0947\u0902 \u092c\u0941\u091c\u093c\u0941\u0930\u094d\u0917 \u0921\u094d\u0930\u093e\u0907\u0935\u0930\u094b\u0902 \u092a\u0930 \u092a\u0921\u093c\u0928\u0947 \u0935\u093e\u0932\u0947 \u0905\u0938\u0930 \u0936\u093e\u092e\u093f\u0932 \u0939\u0948\u0902, \u092e\u0917\u0930 \u0935\u0947 \u0928\u0924\u0940\u091c\u0947 \u092c\u0939\u0938 \u0915\u0947 \u0918\u0947\u0930\u0947 \u092e\u0947\u0902 \u0939\u0948\u0902 \u0914\u0930 \u0906\u092e \u092c\u0941\u0926\u094d\u0927\u093f \u092c\u0922\u093c\u093e\u0928\u0947 \u092f\u093e \u0938\u0902\u091c\u094d\u091e\u093e\u0928\u093e\u0924\u094d\u092e\u0915 \u0917\u093f\u0930\u093e\u0935\u091f \u0930\u094b\u0915\u0928\u0947 \u0915\u0947 \u0926\u0942\u0930\u0917\u093e\u092e\u0940 \u0926\u093e\u0935\u0947 \u0915\u093e\u092b\u093c\u0940 \u0939\u0926 \u0924\u0915 \u0905\u0938\u093e\u092c\u093f\u0924 \u092c\u0928\u0947 \u0939\u0941\u090f \u0939\u0948\u0902, \u0907\u0938\u0932\u093f\u090f \u092c\u0921\u093c\u0947 \u0935\u093e\u0926\u094b\u0902 \u0915\u094b \u0938\u093e\u0935\u0927\u093e\u0928\u0940 \u0938\u0947 \u0932\u0940\u091c\u093f\u090f\u0964",rec:"\u0905\u092a\u0928\u0940 \u0906\u0901\u0916\u0947\u0902 \u0915\u0947\u0902\u0926\u094d\u0930 \u0915\u0947 \u092a\u093e\u0938 \u0930\u0916\u093f\u090f \u0914\u0930 \u0915\u093e\u092e \u0927\u094d\u092f\u093e\u0928 \u0938\u0947 \u0939\u094b\u0928\u0947 \u0926\u0940\u091c\u093f\u090f; \u0939\u0930 \u091a\u0940\u091c\u093c \u092a\u0930 \u0936\u093e\u0930\u0940\u0930\u093f\u0915 \u0930\u0942\u092a \u0938\u0947 \u0928\u091c\u093c\u0930 \u0926\u094c\u0921\u093c\u093e\u0928\u0947 \u0915\u0947 \u092a\u094d\u0930\u0924\u093f\u0935\u0930\u094d\u0924 \u0915\u094b \u0930\u094b\u0915\u093f\u090f, \u0916\u093c\u093e\u0938\u0915\u0930 \u0924\u092c \u091c\u092c \u0915\u0941\u091b \u092d\u0940 \u0909\u092d\u0930\u0915\u0930 \u0938\u093e\u092e\u0928\u0947 \u0928 \u0906\u090f\u0964",faq:[["\u0932\u0915\u094d\u0937\u094d\u092f \u0915\u092d\u0940 \u0924\u0941\u0930\u0902\u0924 \u0909\u092d\u0930\u0915\u0930 \u0938\u093e\u092e\u0928\u0947 \u0915\u094d\u092f\u094b\u0902 \u0906 \u091c\u093e\u0924\u093e \u0939\u0948 \u0914\u0930 \u0915\u092d\u0940 \u0922\u0942\u0901\u0922\u0928\u0947 \u092e\u0947\u0902 \u092f\u0941\u0917 \u0932\u0917 \u091c\u093e\u0924\u0947 \u0939\u0948\u0902?","\u091c\u092c \u0932\u0915\u094d\u0937\u094d\u092f \u0915\u093f\u0938\u0940 \u090f\u0915 \u092c\u0941\u0928\u093f\u092f\u093e\u0926\u0940 \u0935\u093f\u0936\u0947\u0937\u0924\u093e \u0938\u0947, \u091c\u0948\u0938\u0947 \u0930\u0902\u0917 \u092f\u093e \u0926\u093f\u0936\u093e-\u0935\u093f\u0928\u094d\u092f\u093e\u0938 (\u0913\u0930\u093f\u090f\u0902\u091f\u0947\u0936\u0928) \u0938\u0947, \u0905\u0932\u0917 \u0939\u094b\u0924\u093e \u0939\u0948, \u0924\u094b \u0906\u092a\u0915\u093e \u0926\u0943\u0936\u094d\u092f-\u0924\u0902\u0924\u094d\u0930 \u0909\u0938\u0947 \u0915\u0930\u0940\u092c-\u0915\u0930\u0940\u092c \u0938\u092e\u093e\u0928\u093e\u0902\u0924\u0930 \u0930\u0942\u092a \u092e\u0947\u0902 \u092d\u093e\u0901\u092a \u0932\u0947\u0924\u093e \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0935\u0939 \u0909\u092d\u0930\u0915\u0930 \u0938\u093e\u092e\u0928\u0947 \u0906 \u091c\u093e\u0924\u093e \u0939\u0948\u0964 \u091c\u092c \u092f\u0939 \u0938\u093f\u0930\u094d\u092b\u093c \u092d\u091f\u0915\u093e\u0928\u0947 \u0935\u093e\u0932\u094b\u0902 \u0915\u0947 \u0938\u093e\u0925 \u0938\u093e\u091d\u093e \u0935\u093f\u0936\u0947\u0937\u0924\u093e\u0913\u0902 \u0915\u0947 \u090f\u0915 \u0938\u0902\u092f\u094b\u091c\u0928 \u0938\u0947 \u0905\u0932\u0917 \u0939\u094b\u0924\u093e \u0939\u0948, \u0924\u094b \u0906\u092a\u0915\u094b \u091a\u0940\u091c\u093c\u094b\u0902 \u0915\u094b \u0915\u092e\u094b\u092c\u0947\u0936 \u090f\u0915 \u092c\u093e\u0930 \u092e\u0947\u0902 \u090f\u0915 \u0915\u0930\u0915\u0947 \u091c\u093e\u0901\u091a\u0928\u093e \u092a\u0921\u093c\u0924\u093e \u0939\u0948, \u0907\u0938\u0940\u0932\u093f\u090f \u092f\u0939 \u0927\u0940\u092e\u093e \u0914\u0930 \u092e\u0947\u0939\u0928\u0924\u092d\u0930\u093e \u0932\u0917\u0924\u093e \u0939\u0948\u0964"],["\u0915\u094d\u092f\u093e \u092f\u0939 \u092e\u0941\u091d\u0947 \u0905\u0938\u0932 \u091c\u093c\u093f\u0902\u0926\u0917\u0940 \u092e\u0947\u0902 \u091a\u0940\u091c\u093c\u0947\u0902 \u0924\u0947\u091c\u093c\u0940 \u0938\u0947 \u0928\u094b\u091f\u093f\u0938 \u0915\u0930\u0935\u093e\u090f\u0917\u093e, \u091c\u0948\u0938\u0947 \u092d\u0940\u0921\u093c \u092e\u0947\u0902 \u0915\u094b\u0908 \u0926\u094b\u0938\u094d\u0924 \u0922\u0942\u0901\u0922 \u0932\u0947\u0928\u093e?","\u0906\u092a \u0907\u0938 \u0924\u0930\u0939 \u0915\u0947 \u0916\u094b\u091c \u0915\u093e\u0930\u094d\u092f \u092e\u0947\u0902 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0922\u0902\u0917 \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u090f\u0901\u0917\u0947, \u0914\u0930 \u0906\u092a\u0915\u0940 \u091b\u093e\u0928\u092c\u0940\u0928 \u0925\u094b\u0921\u093c\u0940 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0915\u0941\u0936\u0932 \u0939\u094b \u0938\u0915\u0924\u0940 \u0939\u0948\u0964 \u092f\u0939 \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0940 \u0938\u094d\u0925\u093f\u0924\u093f\u092f\u094b\u0902 \u0924\u0915 \u0938\u094d\u0925\u093e\u0928\u093e\u0902\u0924\u0930\u093f\u0924 \u0939\u094b\u0924\u093e \u0939\u0948 \u092f\u093e \u0928\u0939\u0940\u0902, \u092f\u0939 \u0905\u0928\u093f\u0936\u094d\u091a\u093f\u0924 \u0939\u0948 \u0914\u0930 \u092e\u091c\u093c\u092c\u0942\u0924\u0940 \u0938\u0947 \u0938\u093e\u092c\u093f\u0924 \u0928\u0939\u0940\u0902 \u0939\u0941\u0906 \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0908\u092e\u093e\u0928\u0926\u093e\u0930\u0940 \u0907\u0938\u092e\u0947\u0902 \u0939\u0948 \u0915\u093f \u0907\u0938\u0947 \u0915\u093f\u0938\u0940 \u092a\u0915\u094d\u0915\u0947 \u0905\u0938\u0932-\u0926\u0941\u0928\u093f\u092f\u093e \u0905\u092a\u0917\u094d\u0930\u0947\u0921 \u0915\u0947 \u092c\u091c\u093e\u092f \u0926\u0943\u0936\u094d\u092f \u0927\u094d\u092f\u093e\u0928 \u0915\u0947 \u0932\u093f\u090f \u0905\u091a\u094d\u091b\u093e \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u092e\u093e\u0928\u0947\u0902\u0964"],["\u0927\u0940\u0930\u0947 \u0914\u0930 \u0938\u093e\u0935\u0927\u093e\u0928\u0940 \u0938\u0947 \u091b\u093e\u0928\u0928\u093e \u092c\u0947\u0939\u0924\u0930 \u0939\u0948 \u092f\u093e \u091c\u093f\u0924\u0928\u093e \u0924\u0947\u091c\u093c \u0939\u094b \u0938\u0915\u0947 \u091c\u093e\u0928\u093e?","\u092a\u0939\u0932\u0947 \u0938\u091f\u0940\u0915\u0924\u093e \u0917\u0922\u093c\u093f\u090f, \u092b\u093f\u0930 \u0917\u0924\u093f \u091c\u094b\u0921\u093c\u093f\u090f\u0964 \u091a\u0942\u0915\u094b\u0902 \u0938\u0947 \u092d\u0930\u0940 \u0924\u0947\u091c\u093c \u091b\u093e\u0928\u092c\u0940\u0928 \u092c\u0941\u0930\u0940 \u0906\u0926\u0924\u0947\u0902 \u0938\u093f\u0916\u093e\u0924\u0940 \u0939\u0948; \u090f\u0915 \u0938\u094d\u0925\u093f\u0930, \u0935\u094d\u092f\u0935\u0938\u094d\u0925\u093f\u0924 \u092c\u0939\u093e\u0935 \u0915\u093e \u0932\u0915\u094d\u0937\u094d\u092f \u0930\u0916\u093f\u090f \u0914\u0930 \u091c\u0948\u0938\u0947-\u091c\u0948\u0938\u0947 \u0906\u092a\u0915\u0940 \u0906\u0901\u0916\u0947\u0902 \u0938\u0940\u0916\u0924\u0940 \u091c\u093e\u090f\u0901 \u0915\u093f \u0915\u0939\u093e\u0901 \u0926\u0947\u0916\u0928\u093e \u0939\u0948, \u0905\u092a\u0928\u0940 \u0917\u0924\u093f \u0915\u094b \u0905\u092a\u0928\u0947-\u0906\u092a \u092c\u0922\u093c\u0928\u0947 \u0926\u0940\u091c\u093f\u090f\u0964"]],variants:"\u0906\u092e \u092c\u0926\u0932\u093e\u0935\u094b\u0902 \u092e\u0947\u0902 \u0936\u093e\u092e\u093f\u0932 \u0939\u0948\u0902 \u0935\u093f\u0936\u0947\u0937\u0924\u093e-\u0916\u094b\u091c (\u092b\u093c\u0940\u091a\u0930 \u0938\u0930\u094d\u091a), \u091c\u0939\u093e\u0901 \u0932\u0915\u094d\u0937\u094d\u092f \u0915\u093f\u0938\u0940 \u090f\u0915 \u0938\u094d\u092a\u0937\u094d\u091f \u0917\u0941\u0923 \u0938\u0947 \u0905\u0932\u0917 \u0939\u094b\u0924\u093e \u0939\u0948 \u0914\u0930 \u092e\u093e\u0928\u094b \u0909\u091b\u0932\u0915\u0930 \u0938\u093e\u092e\u0928\u0947 \u0906 \u091c\u093e\u0924\u093e \u0939\u0948, \u0914\u0930 \u0938\u0902\u092f\u094b\u091c\u0928-\u0916\u094b\u091c (\u0915\u0902\u091c\u0902\u0915\u094d\u0936\u0928 \u0938\u0930\u094d\u091a), \u091c\u0939\u093e\u0901 \u092f\u0939 \u092d\u091f\u0915\u093e\u0928\u0947 \u0935\u093e\u0932\u094b\u0902 \u0915\u0947 \u0938\u093e\u0925 \u0935\u093f\u0936\u0947\u0937\u0924\u093e\u090f\u0901 \u0938\u093e\u091d\u093e \u0915\u0930\u0924\u093e \u0939\u0948 \u0914\u0930 \u0907\u0938\u0947 \u090f\u0915-\u090f\u0915 \u091a\u0940\u091c\u093c \u0915\u0930\u0915\u0947 \u0916\u094b\u091c\u0928\u093e \u092a\u0921\u093c\u0924\u093e \u0939\u0948\u0964 \u0915\u0920\u093f\u0928\u093e\u0908 \u0915\u094b \u092d\u091f\u0915\u093e\u0928\u0947 \u0935\u093e\u0932\u0947 \u091c\u094b\u0921\u093c\u0915\u0930, \u0905\u0902\u0924\u0930 \u0938\u093f\u0915\u094b\u0921\u093c\u0915\u0930, \u0938\u092e\u092f-\u0938\u0940\u092e\u093e \u0932\u0917\u093e\u0915\u0930, \u092f\u093e \u0932\u0915\u094d\u0937\u094d\u092f \u0915\u094b \u0939\u0930 \u0926\u094c\u0930 \u092c\u0926\u0932\u0928\u0947 \u0935\u093e\u0932\u0947 \u0939\u092e\u0936\u0915\u094d\u0932\u094b\u0902 \u0915\u0947 \u092c\u0940\u091a \u091b\u093f\u092a\u093e\u0915\u0930 \u092c\u0922\u093c\u093e\u092f\u093e \u091c\u093e \u0938\u0915\u0924\u093e \u0939\u0948\u0964"},zh:{about:"\u300a\u89c6\u89c9\u641c\u7d22\u300b\u7ed9\u4f60\u5448\u73b0\u4e00\u7247\u7269\u4f53\uff0c\u8981\u6c42\u4f60\u5728\u4f17\u591a\u5e72\u6270\u9879\u4e2d\u4ee5\u6700\u5feb\u901f\u5ea6\u627e\u5230\u67d0\u4e2a\u7279\u5b9a\u76ee\u6807\uff0c\u7136\u540e\u70b9\u51fb\u5b83\u3002\u6709\u65f6\u76ee\u6807\u51ed\u5355\u4e00\u7279\u5f81\u5c31\u5f88\u624e\u773c\uff0c\u6bd4\u5982\u4e00\u7fa4\u84dd\u70b9\u4e2d\u552f\u4e00\u7684\u90a3\u4e2a\u7ea2\u70b9\uff1b\u6709\u65f6\u5b83\u4e0e\u5e72\u6270\u9879\u5171\u4eab\u6240\u6709\u7279\u5f81\uff0c\u53ea\u6709\u7279\u5f81\u7684\u7ec4\u5408\u624d\u72ec\u4e00\u65e0\u4e8c\uff0c\u6240\u4ee5\u4f60\u5fc5\u987b\u9010\u4e2a\u67e5\u770b\u3002",benefit:"\u5b83\u8bad\u7ec3\u9009\u62e9\u6027\u89c6\u89c9\u6ce8\u610f\uff0c\u4ee5\u53ca\u4f60\u626b\u89c6\u4e00\u4e2a\u573a\u666f\u7684\u6548\u7387\uff1a\u6ee4\u6389\u65e0\u5173\u7684\u6742\u4e71\u3001\u628a\u76ee\u6807\u7684\u5b9a\u4e49\u6027\u7279\u5f81\u8bb0\u5728\u5fc3\u91cc\uff0c\u5e76\u5feb\u901f\u5224\u65ad\u6bcf\u4e2a\u7269\u4f53\u662f\u5426\u5339\u914d\u3002\u968f\u7740\u7ec3\u4e60\uff0c\u4f60\u7684\u641c\u7d22\u4f1a\u53d8\u5f97\u66f4\u5feb\uff0c\u800c\u4f60\u7684\u300e\u6709\u6548\u89c6\u91ce\u300f\u2014\u2014\u4f60\u80fd\u5728\u6ce8\u89c6\u70b9\u5468\u56f4\u4e00\u5e76\u6536\u5165\u773c\u5e95\u7684\u90a3\u7247\u533a\u57df\u2014\u2014\u5f80\u5f80\u4e5f\u4f1a\u53d8\u5bbd\u3002",history:"\u4f5c\u4e3a\u4e00\u79cd\u5b9e\u9a8c\u5ba4\u65b9\u6cd5\uff0c\u89c6\u89c9\u641c\u7d22\u572820\u4e16\u7eaa60\u5e74\u4ee3\u521d\u7531Ulric Neisser\u6210\u5f62\uff0c\u4ed6\u6d4b\u91cf\u4e86\u4eba\u4eec\u626b\u89c6\u6210\u5217\u5b57\u6bcd\u4ee5\u5bfb\u627e\u76ee\u6807\u7684\u65f6\u95f4\u30021980\u5e74\uff0c\u4e00\u9879\u7814\u7a76\u7528\u5b83\u6765\u68c0\u9a8c\u4e00\u4e2a\u91cd\u5927\u7406\u8bba\uff0c\u4f7f\u5b83\u6210\u4e3a\u6ce8\u610f\u7814\u7a76\u7684\u6838\u5fc3\uff0c\u5e76\u7531\u6b64\u6269\u6563\u5230\u4eba\u56e0\u5de5\u7a0b\u3001\u653e\u5c04\u79d1\u548c\u673a\u573a\u5b89\u68c0\u4e2d\uff0c\u6700\u7ec8\u8fdb\u5165\u9762\u5411\u6d88\u8d39\u8005\u7684\u5065\u8111\u5e94\u7528\u3002",creator:"\u8fd9\u9879\u7ec3\u4e60\u672c\u8eab\u6ca1\u6709\u5355\u4e00\u7684\u53d1\u660e\u8005\u3002\u641c\u7d22\u8303\u5f0f\u901a\u5e38\u5f52\u529f\u4e8e20\u4e16\u7eaa60\u5e74\u4ee3\u521d\u7684Ulric Neisser\uff0c\u800c\u5b83\u7531Anne Treisman\u548cGarry Gelade\u57281980\u5e74\u7684\u8bba\u6587\u300a\u6ce8\u610f\u7684\u7279\u5f81\u6574\u5408\u7406\u8bba\u300b\u4e2d\u5f97\u4ee5\u626c\u540d\u2014\u2014\u8be5\u8bba\u6587\u7528\u89c6\u89c9\u641c\u7d22\u5b9e\u9a8c\u8bba\u8bc1\uff1a\u7b80\u5355\u7279\u5f81\u662f\u5e76\u884c\u88ab\u627e\u5230\u7684\uff0c\u800c\u7279\u5f81\u7ec4\u5408\u5219\u5fc5\u987b\u4e00\u6b21\u4e00\u4e2a\u7269\u4f53\u5730\u53bb\u641c\u7d22\u3002",methods:"\u4e0d\u8981\u76ef\u7740\u4e00\u4e2a\u5730\u65b9\u50bb\u7b49\uff1b\u8ba9\u4f60\u7684\u76ee\u5149\u4ee5\u7a33\u5b9a\u3001\u7cfb\u7edf\u7684\u65b9\u5f0f\u626b\u8fc7\u6574\u7247\u533a\u57df\uff0c\u800c\u4e0d\u662f\u968f\u673a\u5730\u8df3\u6765\u8df3\u53bb\u3002\u5728\u5f00\u59cb\u4e4b\u524d\u5148\u628a\u76ee\u6807\u7684\u5b9a\u4e49\u6027\u7279\u5f81\u6e05\u6670\u5730\u8bb0\u5728\u5fc3\u91cc\uff0c\u800c\u5728\u90a3\u4e9b\u6ca1\u6709\u4e1c\u897f\u624e\u773c\u8df3\u51fa\u7684\u300e\u7ec4\u5408\u641c\u7d22\u300f\u8bd5\u9a8c\u91cc\uff0c\u8981\u62b5\u4f4f\u6c42\u5feb\u7684\u51b2\u52a8\uff0c\u63a5\u53d7\u4f60\u5fc5\u987b\u9010\u4e2a\u67e5\u770b\u7269\u4f53\u3002\u53ea\u6709\u5728\u4f60\u7684\u51c6\u786e\u7387\u53ef\u9760\u4e4b\u540e\uff0c\u624d\u8f7b\u8f7b\u5730\u5f80\u901f\u5ea6\u4e0a\u63a8\uff0c\u56e0\u4e3a\u7c97\u5fc3\u7684\u9057\u6f0f\u6bd4\u7565\u6162\u7684\u626b\u89c6\u4ee3\u4ef7\u66f4\u5927\u3002",duration:"\u77ed\u800c\u9891\u7e41\u7684\u7ec3\u4e60\u6548\u679c\u6700\u597d\uff1a\u6bcf\u6b21\u5927\u7ea65\u523010\u5206\u949f\uff0c\u6bcf\u5468\u51e0\u6b21\u3002\u5f53\u4f60\u7684\u53cd\u5e94\u65f6\u5f00\u59cb\u5f80\u4e0a\u98d8\u3001\u6216\u9519\u8bef\u7387\u6500\u5347\u65f6\u5c31\u505c\u4e0b\uff0c\u56e0\u4e3a\u75b2\u60eb\u7684\u641c\u7d22\u5c31\u662f\u9a6c\u864e\u7684\u641c\u7d22\uff0c\u4f60\u4e5f\u4e0d\u518d\u5b66\u5230\u6b63\u786e\u7684\u4e60\u60ef\u3002",research:"\u8bc1\u636e\u6700\u5f3a\u7684\u6070\u6070\u662f\u4f60\u80fd\u6599\u5230\u7684\u90a3\u90e8\u5206\uff1a\u4f60\u4f1a\u5728\u89c6\u89c9\u641c\u7d22\u672c\u8eab\u4e0a\u53d8\u5f97\u66f4\u5feb\u3001\u66f4\u51c6\uff0c\u800c\u76f8\u5173\u8bad\u7ec3\u5df2\u88ab\u8bc1\u660e\u80fd\u62d3\u5bbd\u6709\u6548\u89c6\u91ce\u3002\u66f4\u5bbd\u6cdb\u7684\u90a3\u4e9b\u627f\u8bfa\u5219\u8981\u5f31\u5f97\u591a\u3002\u52a0\u5de5\u901f\u5ea6\u548c\u6709\u6548\u89c6\u91ce\u7684\u8bad\u7ec3\uff0c\u5728\u8fd9\u4e2a\u9886\u57df\u91cc\u62e5\u6709\u4e00\u4e9b\u8f83\u597d\u7684\u73b0\u5b9e\u4e16\u754c\u53d1\u73b0\uff0c\u5305\u62ec\u5bf9\u5e74\u957f\u53f8\u673a\u7684\u5f71\u54cd\uff0c\u4f46\u90a3\u4e9b\u7ed3\u679c\u5b58\u5728\u4e89\u8bae\uff0c\u800c\u5173\u4e8e\u63d0\u5347\u4e00\u822c\u667a\u529b\u6216\u9884\u9632\u8ba4\u77e5\u8870\u9000\u7684\u6df1\u8fdc\u8bf4\u6cd5\u57fa\u672c\u4e0a\u4ecd\u672a\u83b7\u8bc1\u5b9e\uff0c\u6240\u4ee5\u5bf9\u5b8f\u5927\u7684\u627f\u8bfa\u8981\u4fdd\u6301\u8c28\u614e\u3002",rec:"\u8ba9\u4f60\u7684\u773c\u775b\u4fdd\u6301\u5728\u4e2d\u5fc3\u9644\u8fd1\uff0c\u8ba9\u6ce8\u610f\u53bb\u5b8c\u6210\u5de5\u4f5c\uff1b\u62b5\u4f4f\u90a3\u79cd\u671d\u6bcf\u4e2a\u7269\u4f53\u731b\u7136\u626b\u89c6\u7684\u672c\u80fd\u53cd\u5c04\uff0c\u5c24\u5176\u662f\u5728\u6ca1\u6709\u4e1c\u897f\u624e\u773c\u8df3\u51fa\u7684\u65f6\u5019\u3002",faq:[["\u4e3a\u4ec0\u4e48\u76ee\u6807\u6709\u65f6\u4e00\u77ac\u95f4\u5c31\u8df3\u51fa\u6765\uff0c\u6709\u65f6\u5374\u8981\u627e\u4e0a\u8001\u534a\u5929\uff1f","\u5f53\u76ee\u6807\u51ed\u5355\u4e00\u7684\u57fa\u672c\u7279\u5f81\uff08\u6bd4\u5982\u989c\u8272\u6216\u671d\u5411\uff09\u4e0e\u4f17\u4e0d\u540c\u65f6\uff0c\u4f60\u7684\u89c6\u89c9\u7cfb\u7edf\u51e0\u4e4e\u662f\u5e76\u884c\u5730\u628a\u5b83\u8ba4\u51fa\u6765\uff0c\u6240\u4ee5\u5b83\u4f1a\u8df3\u51fa\u6765\u3002\u800c\u5f53\u5b83\u53ea\u662f\u51ed\u4e00\u4e2a\u4e0e\u5e72\u6270\u9879\u5171\u4eab\u7684\u7279\u5f81\u7ec4\u5408\u800c\u4e0d\u540c\u65f6\uff0c\u4f60\u5c31\u5f97\u6216\u591a\u6216\u5c11\u5730\u4e00\u6b21\u4e00\u4e2a\u53bb\u67e5\u770b\uff0c\u8fd9\u6b63\u662f\u5b83\u611f\u89c9\u53c8\u6162\u53c8\u8d39\u52b2\u7684\u539f\u56e0\u3002"],["\u8fd9\u4f1a\u8ba9\u6211\u5728\u73b0\u5b9e\u751f\u6d3b\u4e2d\u66f4\u5feb\u6ce8\u610f\u5230\u4e1c\u897f\u5417\uff0c\u6bd4\u5982\u5728\u4eba\u7fa4\u91cc\u8ba4\u51fa\u670b\u53cb\uff1f","\u4f60\u4e00\u5b9a\u4f1a\u5728\u8fd9\u7c7b\u641c\u7d22\u4efb\u52a1\u4e0a\u53d8\u5f97\u66f4\u597d\uff0c\u4f60\u7684\u626b\u89c6\u6216\u8bb8\u4e5f\u4f1a\u53d8\u5f97\u7a0d\u5fae\u9ad8\u6548\u4e00\u4e9b\u3002\u81f3\u4e8e\u8fd9\u80fd\u5426\u5ef6\u7eed\u5230\u65e5\u5e38\u60c5\u5883\u5219\u4e0d\u786e\u5b9a\u3001\u4e5f\u6ca1\u6709\u5f3a\u6709\u529b\u7684\u8bc1\u660e\uff0c\u6240\u4ee5\u8bda\u5b9e\u5730\u8bf4\uff0c\u628a\u5b83\u5f53\u4f5c\u5bf9\u89c6\u89c9\u6ce8\u610f\u7684\u826f\u597d\u8bad\u7ec3\uff0c\u800c\u4e0d\u662f\u4e00\u6b21\u6709\u4fdd\u8bc1\u7684\u73b0\u5b9e\u4e16\u754c\u5347\u7ea7\u3002"],["\u662f\u6162\u800c\u4ed4\u7ec6\u5730\u626b\u89c6\u66f4\u597d\uff0c\u8fd8\u662f\u5c3d\u53ef\u80fd\u5feb\u5730\u626b\u66f4\u597d\uff1f","\u5148\u5efa\u7acb\u51c6\u786e\uff0c\u518d\u52a0\u901f\u5ea6\u3002\u4e00\u6b21\u5145\u6ee1\u9057\u6f0f\u7684\u5feb\u901f\u626b\u89c6\u4f1a\u6559\u51fa\u574f\u4e60\u60ef\uff1b\u76ee\u6807\u662f\u7a33\u5b9a\u3001\u7cfb\u7edf\u7684\u626b\u89c6\uff0c\u8ba9\u4f60\u7684\u901f\u5ea6\u968f\u7740\u773c\u775b\u5b66\u4f1a\u8be5\u5f80\u54ea\u513f\u770b\u800c\u81ea\u7136\u63d0\u5347\u3002"]],variants:"\u5e38\u89c1\u7684\u53d8\u4f53\u5305\u62ec\u7279\u5f81\u641c\u7d22\u2014\u2014\u76ee\u6807\u51ed\u4e00\u4e2a\u660e\u663e\u7684\u5c5e\u6027\u4e0e\u4f17\u4e0d\u540c\u3001\u4eff\u4f5b\u4f1a\u8df3\u51fa\u6765\uff1b\u4ee5\u53ca\u7ec4\u5408\u641c\u7d22\u2014\u2014\u76ee\u6807\u4e0e\u5e72\u6270\u9879\u5171\u4eab\u7279\u5f81\uff0c\u5fc5\u987b\u9010\u4e2a\u53bb\u641c\u5bfb\u3002\u96be\u5ea6\u53ef\u4ee5\u901a\u8fc7\u589e\u52a0\u5e72\u6270\u9879\u3001\u7f29\u5c0f\u5dee\u5f02\u3001\u8bbe\u7f6e\u65f6\u95f4\u9650\u5236\uff0c\u6216\u628a\u76ee\u6807\u85cf\u5728\u6bcf\u8f6e\u90fd\u4f1a\u53d8\u5316\u7684\u76f8\u4f3c\u7269\u4e2d\u6765\u52a0\u4ee5\u8c03\u8282\u3002"}},wcst:{ru:{about:"WCST: \u041f\u0440\u0430\u0432\u0438\u043b\u0430 \u2014 \u044d\u0442\u043e \u0441\u043e\u0440\u0442\u0438\u0440\u043e\u0432\u043a\u0430 \u043a\u0430\u0440\u0442\u043e\u0447\u0435\u043a \u043d\u0430 \u043e\u0441\u043d\u043e\u0432\u0435 \u0412\u0438\u0441\u043a\u043e\u043d\u0441\u0438\u043d\u0441\u043a\u043e\u0433\u043e \u0442\u0435\u0441\u0442\u0430 \u0441\u043e\u0440\u0442\u0438\u0440\u043e\u0432\u043a\u0438 \u043a\u0430\u0440\u0442\u043e\u0447\u0435\u043a. \u0412\u044b \u043f\u043e\u0434\u0431\u0438\u0440\u0430\u0435\u0442\u0435 \u043a\u0430\u0436\u0434\u0443\u044e \u043a\u0430\u0440\u0442\u043e\u0447\u043a\u0443 \u043a \u043e\u0434\u043d\u043e\u0439 \u0438\u0437 \u044d\u0442\u0430\u043b\u043e\u043d\u043d\u044b\u0445, \u043d\u043e \u043f\u0440\u0430\u0432\u0438\u043b\u043e \u043f\u043e\u0434\u0431\u043e\u0440\u0430 (\u0446\u0432\u0435\u0442, \u0444\u043e\u0440\u043c\u0430 \u0438\u043b\u0438 \u043a\u043e\u043b\u0438\u0447\u0435\u0441\u0442\u0432\u043e) \u0432\u0430\u043c \u043d\u0435 \u0441\u043e\u043e\u0431\u0449\u0430\u044e\u0442 \u2014 \u0432\u044b \u0432\u044b\u0432\u043e\u0434\u0438\u0442\u0435 \u0435\u0433\u043e \u0441\u0430\u043c\u0438 \u043f\u043e \u043a\u043e\u0440\u043e\u0442\u043a\u043e\u043c\u0443 \xab\u0432\u0435\u0440\u043d\u043e\xbb \u0438\u043b\u0438 \xab\u043d\u0435\u0432\u0435\u0440\u043d\u043e\xbb \u043f\u043e\u0441\u043b\u0435 \u043a\u0430\u0436\u0434\u043e\u0433\u043e \u0445\u043e\u0434\u0430, \u0430 \u043a\u0430\u043a \u0442\u043e\u043b\u044c\u043a\u043e \u043d\u0430\u0449\u0443\u043f\u0430\u043b\u0438 \u2014 \u043f\u0440\u0430\u0432\u0438\u043b\u043e \u043d\u0435\u0437\u0430\u043c\u0435\u0442\u043d\u043e \u043c\u0435\u043d\u044f\u0435\u0442\u0441\u044f, \u0438 \u043d\u0443\u0436\u043d\u043e \u0438\u0441\u043a\u0430\u0442\u044c \u043d\u043e\u0432\u043e\u0435.",benefit:"\u0422\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u043a\u043e\u0433\u043d\u0438\u0442\u0438\u0432\u043d\u0443\u044e \u0433\u0438\u0431\u043a\u043e\u0441\u0442\u044c \u0438 \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0435\u043d\u0438\u0435 \u0443\u0441\u0442\u0430\u043d\u043e\u0432\u043a\u0438: \u0443\u043c\u0435\u043d\u0438\u0435 \u0431\u0440\u043e\u0441\u0438\u0442\u044c \u043f\u0440\u0430\u0432\u0438\u043b\u043e, \u043a\u043e\u0442\u043e\u0440\u043e\u0435 \u0442\u043e\u043b\u044c\u043a\u043e \u0447\u0442\u043e \u043f\u0435\u0440\u0435\u0441\u0442\u0430\u043b\u043e \u0440\u0430\u0431\u043e\u0442\u0430\u0442\u044c, \u0438 \u043f\u0435\u0440\u0435\u0439\u0442\u0438 \u043a \u043d\u043e\u0432\u043e\u043c\u0443, \u043d\u0435 \u0437\u0430\u0441\u0442\u0440\u0435\u0432\u0430\u044f \u043d\u0430 \u0441\u0442\u0430\u0440\u043e\u043c. \u041f\u043e\u043f\u0443\u0442\u043d\u043e \u0440\u0430\u0431\u043e\u0442\u0430\u044e\u0442 \u043e\u0431\u0443\u0447\u0435\u043d\u0438\u0435 \u043f\u043e \u043e\u0431\u0440\u0430\u0442\u043d\u043e\u0439 \u0441\u0432\u044f\u0437\u0438, \u0440\u0430\u0431\u043e\u0447\u0430\u044f \u043f\u0430\u043c\u044f\u0442\u044c \u0438 \u0442\u043e\u0440\u043c\u043e\u0436\u0435\u043d\u0438\u0435 \u043f\u0440\u0438\u0432\u044b\u0447\u043d\u043e\u0439 \u0440\u0435\u0430\u043a\u0446\u0438\u0438.",history:"\u0417\u0430\u0434\u0430\u0447\u0430 \u0432\u044b\u0440\u043e\u0441\u043b\u0430 \u0438\u0437 \u0435\u0432\u0440\u043e\u043f\u0435\u0439\u0441\u043a\u0438\u0445 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u0439 \u0444\u043e\u0440\u043c\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u044f \u043f\u043e\u043d\u044f\u0442\u0438\u0439 \u0438 \u0441\u043e\u0440\u0442\u0438\u0440\u043e\u0432\u043a\u0438 (\u041d\u0430\u0440\u0446\u0438\u0441\u0441 \u0410\u0445, \u041a\u0443\u0440\u0442 \u0413\u043e\u043b\u044c\u0434\u0448\u0442\u0435\u0439\u043d) \u0438 \u0431\u044b\u043b\u0430 \u043e\u0444\u043e\u0440\u043c\u043b\u0435\u043d\u0430 \u0432 \u0412\u0438\u0441\u043a\u043e\u043d\u0441\u0438\u043d\u0441\u043a\u043e\u043c \u0443\u043d\u0438\u0432\u0435\u0440\u0441\u0438\u0442\u0435\u0442\u0435 \u0432 1940-\u0445. \u0421 1960-\u0445, \u043e\u0441\u043e\u0431\u0435\u043d\u043d\u043e \u043f\u043e\u0441\u043b\u0435 \u0440\u0430\u0431\u043e\u0442 \u0411\u0440\u0435\u043d\u0434\u044b \u041c\u0438\u043b\u043d\u0435\u0440, \u0441\u0432\u044f\u0437\u0430\u0432\u0448\u0438\u0445 \u043d\u0438\u0437\u043a\u0438\u0439 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442 \u0441 \u043f\u043e\u0440\u0430\u0436\u0435\u043d\u0438\u0435\u043c \u043b\u043e\u0431\u043d\u044b\u0445 \u0434\u043e\u043b\u0435\u0439, \u0442\u0435\u0441\u0442 \u0441\u0442\u0430\u043b \u043e\u0434\u043d\u0438\u043c \u0438\u0437 \u0441\u0430\u043c\u044b\u0445 \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0435\u043c\u044b\u0445 \u0432 \u043a\u043b\u0438\u043d\u0438\u0447\u0435\u0441\u043a\u043e\u0439 \u043d\u0435\u0439\u0440\u043e\u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u0438\u0438, \u0430 \u0441\u0435\u0433\u043e\u0434\u043d\u044f \u0436\u0438\u0432\u0451\u0442 \u0438 \u0432 \u043f\u0440\u0438\u043b\u043e\u0436\u0435\u043d\u0438\u044f\u0445 \u0434\u043b\u044f \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0438 \u043c\u043e\u0437\u0433\u0430.",creator:"\u041e\u043f\u0443\u0431\u043b\u0438\u043a\u043e\u0432\u0430\u043d \u0432 1948 \u0433\u043e\u0434\u0443 \u0432 Journal of Experimental Psychology \u0414\u044d\u0432\u0438\u0434\u043e\u043c \u0413\u0440\u0430\u043d\u0442\u043e\u043c \u0438 \u042d\u0441\u0442\u043e\u0439 \u0411\u0435\u0440\u0433 \u0432 \u0412\u0438\u0441\u043a\u043e\u043d\u0441\u0438\u043d\u0441\u043a\u043e\u043c \u0443\u043d\u0438\u0432\u0435\u0440\u0441\u0438\u0442\u0435\u0442\u0435; \u0432 \u043e\u0441\u043d\u043e\u0432\u0435 \u2014 \u0431\u043e\u043b\u0435\u0435 \u0440\u0430\u043d\u043d\u044f\u044f \u043c\u0430\u0433\u0438\u0441\u0442\u0435\u0440\u0441\u043a\u0430\u044f \u0440\u0430\u0431\u043e\u0442\u0430 \u0411\u0435\u0440\u0433. \u042d\u0442\u043e \u043d\u0435 \u0438\u0437\u043e\u0431\u0440\u0435\u0442\u0435\u043d\u0438\u0435 \u0441 \u043d\u0443\u043b\u044f, \u0430 \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u0435 \u0441\u0442\u0430\u0440\u043e\u0439 \u0435\u0432\u0440\u043e\u043f\u0435\u0439\u0441\u043a\u043e\u0439 \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u0438 \u0437\u0430\u0434\u0430\u0447 \u043d\u0430 \u0444\u043e\u0440\u043c\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u0435 \u043f\u043e\u043d\u044f\u0442\u0438\u0439 \u0438 \u0441\u043e\u0440\u0442\u0438\u0440\u043e\u0432\u043a\u0443.",methods:"\u041b\u044e\u0431\u043e\u0439 \u043d\u0435\u0432\u0435\u0440\u043d\u044b\u0439 \u043e\u0442\u0432\u0435\u0442 \u2014 \u044d\u0442\u043e \u043d\u0435 \u043f\u0440\u043e\u0432\u0430\u043b, \u0430 \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u043a\u0430: \u043e\u043d \u0433\u043e\u0432\u043e\u0440\u0438\u0442, \u0447\u0442\u043e \u0442\u0435\u043a\u0443\u0449\u0435\u0435 \u043f\u0440\u0430\u0432\u0438\u043b\u043e \u043d\u0435 \u0442\u043e, \u0438 \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0430\u0442\u044c\u0441\u044f \u043d\u0430\u0434\u043e \u043e\u0441\u043e\u0437\u043d\u0430\u043d\u043d\u043e, \u0430 \u043d\u0435 \u043d\u0430\u0443\u0433\u0430\u0434. \u0421\u0444\u043e\u0440\u043c\u0443\u043b\u0438\u0440\u0443\u0439\u0442\u0435 \u044f\u0432\u043d\u0443\u044e \u0433\u0438\u043f\u043e\u0442\u0435\u0437\u0443 (\xab\u0442\u0435\u043f\u0435\u0440\u044c \u043f\u043e \u0446\u0432\u0435\u0442\u0443\xbb), \u043f\u0440\u043e\u0432\u0435\u0440\u044c\u0442\u0435 \u0435\u0451 \u0438, \u043a\u0430\u043a \u0442\u043e\u043b\u044c\u043a\u043e \u043e\u0431\u0440\u0430\u0442\u043d\u0430\u044f \u0441\u0432\u044f\u0437\u044c \u0435\u0451 \u043e\u043f\u0440\u043e\u0432\u0435\u0440\u0433\u043b\u0430, \u0431\u0440\u043e\u0441\u0430\u0439\u0442\u0435 \u0431\u044b\u0441\u0442\u0440\u043e \u2014 \u0434\u0435\u0440\u0436\u0430\u0442\u044c\u0441\u044f \u0437\u0430 \u043c\u0451\u0440\u0442\u0432\u043e\u0435 \u043f\u0440\u0430\u0432\u0438\u043b\u043e \u0434\u043e\u0440\u043e\u0436\u0435 \u0432\u0441\u0435\u0433\u043e. \u0421\u0440\u0430\u0437\u0443 \u043f\u043e\u0441\u043b\u0435 \u0441\u043c\u0435\u043d\u044b \u043f\u0440\u0430\u0432\u0438\u043b\u0430 \u0441\u043e\u0445\u0440\u0430\u043d\u044f\u0439\u0442\u0435 \u0445\u043e\u043b\u043e\u0434\u043d\u0443\u044e \u0433\u043e\u043b\u043e\u0432\u0443: \u0438\u043c\u0435\u043d\u043d\u043e \u0437\u0434\u0435\u0441\u044c \u0441\u043a\u0430\u043f\u043b\u0438\u0432\u0430\u0435\u0442\u0441\u044f \u0431\u043e\u043b\u044c\u0448\u0438\u043d\u0441\u0442\u0432\u043e \u043e\u0448\u0438\u0431\u043e\u043a.",duration:"\u041a\u043e\u0440\u043e\u0442\u043a\u043e \u0438 \u0440\u0435\u0433\u0443\u043b\u044f\u0440\u043d\u043e \u043b\u0443\u0447\u0448\u0435, \u0447\u0435\u043c \u0434\u043e\u043b\u0433\u043e \u0438 \u0440\u0435\u0434\u043a\u043e: 5\u201310 \u043c\u0438\u043d\u0443\u0442 \u0437\u0430 \u043f\u043e\u0434\u0445\u043e\u0434, \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0440\u0430\u0437 \u0432 \u043d\u0435\u0434\u0435\u043b\u044e \u2014 \u0434\u043e\u0441\u0442\u0430\u0442\u043e\u0447\u043d\u043e. \u041e\u0441\u0442\u0430\u043d\u0430\u0432\u043b\u0438\u0432\u0430\u0439\u0442\u0435\u0441\u044c, \u043a\u043e\u0433\u0434\u0430 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u0435 \u043f\u043e\u043f\u043b\u044b\u043b\u043e: \u0443\u0441\u0442\u0430\u043b\u043e\u0441\u0442\u044c \u0434\u0430\u0451\u0442 \u0440\u043e\u0432\u043d\u043e \u0442\u0435 \u0440\u0438\u0433\u0438\u0434\u043d\u044b\u0435 \u043f\u043e\u0432\u0442\u043e\u0440\u044f\u044e\u0449\u0438\u0435\u0441\u044f \u043e\u0448\u0438\u0431\u043a\u0438, \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u0437\u0430\u0434\u0430\u0447\u0430 \u0438 \u043f\u0440\u0438\u0437\u0432\u0430\u043d\u0430 \u0443\u0431\u0440\u0430\u0442\u044c.",research:"\u041d\u0430\u0434\u0451\u0436\u043d\u0435\u0435 \u0432\u0441\u0435\u0433\u043e \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043d\u043e \u043e\u0436\u0438\u0434\u0430\u0435\u043c\u043e\u0435 \u2014 \u0432\u044b \u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u0435\u0441\u044c \u043b\u0443\u0447\u0448\u0435 \u0432 \u0441\u0430\u043c\u043e\u0439 \u0437\u0430\u0434\u0430\u0447\u0435 \u0438 \u0432 \u0431\u043b\u0438\u0437\u043a\u0438\u0445 \u0437\u0430\u0434\u0430\u0447\u0430\u0445 \u043d\u0430 \u0441\u043e\u0440\u0442\u0438\u0440\u043e\u0432\u043a\u0443 \u0438 \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0435\u043d\u0438\u0435, \u0430 \u043a\u0430\u043a \u043a\u043b\u0438\u043d\u0438\u0447\u0435\u0441\u043a\u0438\u0439 \u0438\u043d\u0441\u0442\u0440\u0443\u043c\u0435\u043d\u0442 \u0442\u0435\u0441\u0442 \u0432\u0430\u043b\u0438\u0434\u0435\u043d \u0438 \u0447\u0443\u0432\u0441\u0442\u0432\u0438\u0442\u0435\u043b\u0435\u043d \u043a \u043d\u0430\u0440\u0443\u0448\u0435\u043d\u0438\u044f\u043c \u0438\u0441\u043f\u043e\u043b\u043d\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0445 \u0444\u0443\u043d\u043a\u0446\u0438\u0439 \u0438 \u0440\u0430\u0431\u043e\u0442\u044b \u043b\u043e\u0431\u043d\u044b\u0445 \u0434\u043e\u043b\u0435\u0439. \u041d\u043e \u043e\u043d \u0447\u0443\u0432\u0441\u0442\u0432\u0438\u0442\u0435\u043b\u0435\u043d, \u0430 \u043d\u0435 \u0441\u043f\u0435\u0446\u0438\u0444\u0438\u0447\u0435\u043d: \u0441\u043b\u0430\u0431\u044b\u0439 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442 \u043c\u043e\u0436\u0435\u0442 \u0438\u0434\u0442\u0438 \u043e\u0442 \u0432\u043d\u0438\u043c\u0430\u043d\u0438\u044f \u0438\u043b\u0438 \u043f\u0430\u043c\u044f\u0442\u0438, \u0430 \u043d\u0435 \u0442\u043e\u043b\u044c\u043a\u043e \u043e\u0442 \u0433\u0438\u0431\u043a\u043e\u0441\u0442\u0438; \u0440\u0435\u0442\u0435\u0441\u0442\u043e\u0432\u0430\u044f \u043d\u0430\u0434\u0451\u0436\u043d\u043e\u0441\u0442\u044c \u043b\u0438\u0448\u044c \u0443\u043c\u0435\u0440\u0435\u043d\u043d\u0430\u044f, \u0430 \u0433\u0440\u043e\u043c\u043a\u0438\u0435 \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f \u2014 \u0447\u0442\u043e \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0430 \u043f\u043e\u0434\u043d\u0438\u043c\u0430\u0435\u0442 \u043e\u0431\u0449\u0438\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0438\u043b\u0438 \u0448\u0438\u0440\u043e\u043a\u043e \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0438\u0442\u0441\u044f \u043d\u0430 \u043f\u043e\u0432\u0441\u0435\u0434\u043d\u0435\u0432\u043d\u044b\u0435 \u0440\u0435\u0448\u0435\u043d\u0438\u044f \u2014 \u043f\u043e \u0431\u043e\u043b\u044c\u0448\u0435\u0439 \u0447\u0430\u0441\u0442\u0438 \u043d\u0435 \u0434\u043e\u043a\u0430\u0437\u0430\u043d\u044b. \u041a \u0442\u0430\u043a\u0438\u043c \u0437\u0430\u044f\u0432\u043b\u0435\u043d\u0438\u044f\u043c \u0441\u0442\u043e\u0438\u0442 \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u044c\u0441\u044f \u043e\u0441\u0442\u043e\u0440\u043e\u0436\u043d\u043e.",rec:"\u0421\u0440\u0430\u0437\u0443 \u043f\u043e\u0441\u043b\u0435 \u0441\u043c\u0435\u043d\u044b \u043f\u0440\u0430\u0432\u0438\u043b\u0430 \u0432\u044b\u0434\u0435\u0440\u0436\u0438\u0442\u0435 \u043f\u0430\u0443\u0437\u0443 \u0432 \u043e\u0434\u0438\u043d \u0443\u0434\u0430\u0440 \u2014 \u044d\u0442\u0430 \u0441\u0435\u043a\u0443\u043d\u0434\u0430 \u0441\u043d\u0438\u043c\u0430\u0435\u0442 \u0431\u043e\u043b\u044c\u0448\u0443\u044e \u0447\u0430\u0441\u0442\u044c \u043f\u0435\u0440\u0441\u0435\u0432\u0435\u0440\u0430\u0442\u043e\u0440\u043d\u044b\u0445 \u043e\u0448\u0438\u0431\u043e\u043a.",faq:[["\u041f\u043e\u0447\u0435\u043c\u0443 \u043f\u0440\u0430\u0432\u0438\u043b\u043e \u0432\u0441\u0451 \u0432\u0440\u0435\u043c\u044f \u043c\u0435\u043d\u044f\u0435\u0442\u0441\u044f \u0438 \u043c\u043d\u0435 \u043e\u0431 \u044d\u0442\u043e\u043c \u043d\u0435 \u0433\u043e\u0432\u043e\u0440\u044f\u0442?","\u0421\u043a\u0440\u044b\u0442\u0430\u044f \u0441\u043c\u0435\u043d\u0430 \u2014 \u044d\u0442\u043e \u0438 \u0435\u0441\u0442\u044c \u0441\u0443\u0442\u044c. \u0417\u0430\u0434\u0430\u0447\u0430 \u0438\u0437\u043c\u0435\u0440\u044f\u0435\u0442, \u043a\u0430\u043a \u0431\u044b\u0441\u0442\u0440\u043e \u0432\u044b \u0437\u0430\u043c\u0435\u0447\u0430\u0435\u0442\u0435, \u0447\u0442\u043e \u0441\u0442\u0430\u0440\u043e\u0435 \u043f\u0440\u0430\u0432\u0438\u043b\u043e \u043f\u0435\u0440\u0435\u0441\u0442\u0430\u043b\u043e \u0440\u0430\u0431\u043e\u0442\u0430\u0442\u044c, \u0438 \u043f\u0435\u0440\u0435\u0445\u043e\u0434\u0438\u0442\u0435 \u043a \u043d\u043e\u0432\u043e\u043c\u0443; \u043e\u0431\u044a\u044f\u0432\u043b\u0435\u043d\u043d\u043e\u0435 \u043f\u0440\u0430\u0432\u0438\u043b\u043e \u0443\u0431\u0440\u0430\u043b\u043e \u0431\u044b \u0440\u043e\u0432\u043d\u043e \u0442\u043e\u0442 \u043d\u0430\u0432\u044b\u043a, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u0442\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442\u0441\u044f."],["\u042f \u043f\u0440\u043e\u0434\u043e\u043b\u0436\u0430\u044e \u0441\u043e\u0440\u0442\u0438\u0440\u043e\u0432\u0430\u0442\u044c \u043f\u043e \u043e\u0434\u043d\u043e\u043c\u0443 \u043f\u0440\u0438\u0437\u043d\u0430\u043a\u0443 \u0434\u0430\u0436\u0435 \u043f\u043e\u0441\u043b\u0435 \u043e\u0448\u0438\u0431\u043a\u0438 \u2014 \u044d\u0442\u043e \u043f\u043b\u043e\u0445\u043e?","\u041f\u043e\u0432\u0442\u043e\u0440 \u043f\u0440\u0430\u0432\u0438\u043b\u0430, \u043a\u043e\u0442\u043e\u0440\u043e\u0435 \u0443\u0436\u0435 \u043d\u0435 \u0440\u0430\u0431\u043e\u0442\u0430\u0435\u0442, \u043d\u0430\u0437\u044b\u0432\u0430\u0435\u0442\u0441\u044f \u043f\u0435\u0440\u0441\u0435\u0432\u0435\u0440\u0430\u0442\u043e\u0440\u043d\u043e\u0439 \u043e\u0448\u0438\u0431\u043a\u043e\u0439, \u0438 \u044d\u0442\u043e \u0441\u0430\u043c\u044b\u0439 \u0438\u043d\u0444\u043e\u0440\u043c\u0430\u0442\u0438\u0432\u043d\u044b\u0439 \u0441\u0438\u0433\u043d\u0430\u043b \u0437\u0434\u0435\u0441\u044c. \u0421\u0430\u043c \u043d\u0430\u0432\u044b\u043a \u0432 \u0442\u043e\u043c \u0438 \u0441\u043e\u0441\u0442\u043e\u0438\u0442, \u0447\u0442\u043e\u0431\u044b \u0437\u0430\u043c\u0435\u0442\u0438\u0442\u044c \u0438 \u0440\u0430\u0437\u043e\u0440\u0432\u0430\u0442\u044c \u044d\u0442\u0443 \u043f\u0435\u0442\u043b\u044e, \u0442\u0430\u043a \u0447\u0442\u043e \u043f\u043e\u0439\u043c\u0430\u0442\u044c \u0441\u0435\u0431\u044f \u043d\u0430 \u043d\u0435\u0439 \u2014 \u0443\u0436\u0435 \u043f\u0440\u043e\u0433\u0440\u0435\u0441\u0441."],["\u042d\u0442\u043e \u0441\u0434\u0435\u043b\u0430\u0435\u0442 \u043c\u0435\u043d\u044f \u0443\u043c\u043d\u0435\u0435 \u0438\u043b\u0438 \u043b\u0443\u0447\u0448\u0435 \u0432 \u0440\u0435\u0448\u0435\u043d\u0438\u044f\u0445 \u0432\u043e\u043e\u0431\u0449\u0435?","\u0427\u0435\u0441\u0442\u043d\u043e \u2014 \u0432\u0440\u044f\u0434 \u043b\u0438 \u0432 \u0448\u0438\u0440\u043e\u043a\u043e\u043c \u0441\u043c\u044b\u0441\u043b\u0435. \u0412\u044b \u0443\u0441\u0442\u043e\u0439\u0447\u0438\u0432\u043e \u0441\u0442\u0430\u043d\u0435\u0442\u0435 \u043b\u0443\u0447\u0448\u0435 \u0432 \u0437\u0430\u0434\u0430\u0447\u0430\u0445 \u043d\u0430 \u0441\u043e\u0440\u0442\u0438\u0440\u043e\u0432\u043a\u0443 \u0438 \u043f\u0435\u0440\u0435\u043a\u043b\u044e\u0447\u0435\u043d\u0438\u0435 \u043f\u0440\u0430\u0432\u0438\u043b, \u043d\u043e \u0442\u0432\u0451\u0440\u0434\u044b\u0445 \u0434\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432, \u0447\u0442\u043e \u044d\u0442\u043e \u043f\u043e\u0434\u043d\u0438\u043c\u0430\u0435\u0442 \u043e\u0431\u0449\u0438\u0439 \u0438\u043d\u0442\u0435\u043b\u043b\u0435\u043a\u0442 \u0438\u043b\u0438 \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0438\u0442\u0441\u044f \u043d\u0430 \u0431\u044b\u0442\u043e\u0432\u044b\u0435 \u0440\u0435\u0448\u0435\u043d\u0438\u044f, \u043d\u0435\u0442. \u0422\u0440\u0435\u043d\u0438\u0440\u0443\u0439\u0442\u0435 \u0440\u0430\u0434\u0438 \u043f\u043e\u043b\u0435\u0437\u043d\u043e\u0433\u043e \u043d\u0430\u0432\u044b\u043a\u0430, \u0430 \u043d\u0435 \u0440\u0430\u0434\u0438 \u043f\u0440\u0438\u0431\u0430\u0432\u043a\u0438 \u043a IQ."]],variants:"\u0412\u0435\u0440\u0441\u0438\u0438 \u0440\u0430\u0437\u043b\u0438\u0447\u0430\u044e\u0442\u0441\u044f \u0447\u0438\u0441\u043b\u043e\u043c \u043a\u0430\u0440\u0442\u043e\u0447\u0435\u043a, \u0442\u0435\u043c, \u043c\u0435\u043d\u044f\u0435\u0442\u0441\u044f \u043b\u0438 \u043f\u0440\u0430\u0432\u0438\u043b\u043e \u043f\u043e \u0444\u0438\u043a\u0441\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u043e\u043c\u0443 \u0433\u0440\u0430\u0444\u0438\u043a\u0443 \u0438\u043b\u0438 \u043d\u0435\u043f\u0440\u0435\u0434\u0441\u043a\u0430\u0437\u0443\u0435\u043c\u043e, \u0438 \u043e\u0431\u044a\u0451\u043c\u043e\u043c \u043e\u0431\u0440\u0430\u0442\u043d\u043e\u0439 \u0441\u0432\u044f\u0437\u0438. \u0423\u043a\u043e\u0440\u043e\u0447\u0435\u043d\u043d\u044b\u0435 \u0444\u043e\u0440\u043c\u044b (\u043d\u0430\u043f\u0440\u0438\u043c\u0435\u0440, 48-\u043a\u0430\u0440\u0442\u043e\u0447\u043d\u0430\u044f \u0432\u0435\u0440\u0441\u0438\u044f \u041d\u0435\u043b\u044c\u0441\u043e\u043d\u0430) \u0443\u0431\u0438\u0440\u0430\u044e\u0442 \u0434\u0432\u0443\u0441\u043c\u044b\u0441\u043b\u0435\u043d\u043d\u044b\u0435 \u043a\u0430\u0440\u0442\u043e\u0447\u043a\u0438, \u043a\u043e\u043c\u043f\u044c\u044e\u0442\u0435\u0440\u043d\u044b\u0435 \u0440\u0435\u0434\u0430\u043a\u0446\u0438\u0438 \u0434\u043e\u0431\u0430\u0432\u043b\u044f\u044e\u0442 \u0437\u0430\u043c\u0435\u0440 \u0432\u0440\u0435\u043c\u0435\u043d\u0438 \u0438 \u0441\u043a\u043e\u0440\u043e\u0441\u0442\u0438 \u0440\u0435\u0430\u043a\u0446\u0438\u0438, \u0430 \u0434\u0435\u0442\u0441\u043a\u0438\u0435 \u0432\u0430\u0440\u0438\u0430\u043d\u0442\u044b \u0432\u0440\u043e\u0434\u0435 Dimensional Change Card Sort \u0443\u043f\u0440\u043e\u0449\u0430\u044e\u0442 \u043f\u0440\u0430\u0432\u0438\u043b\u0430 \u0434\u043b\u044f \u043c\u043b\u0430\u0434\u0448\u0438\u0445."},en:{about:"WCST: Rules is a card-sorting task built on the Wisconsin Card Sorting Test. You match each card to one of several reference cards, but you are never told the matching rule (colour, shape, or number) \u2014 you infer it from a simple right or wrong after each move, and the moment you have it figured out the rule silently changes and you have to find the new one.",benefit:"It trains cognitive flexibility and set-shifting: the ability to drop a rule that just stopped working and switch to a new one without getting stuck. Along the way it exercises feedback-based learning, working memory, and the inhibition needed to stop repeating a habit.",history:"The task grew out of European studies of concept formation and sorting (Narziss Ach, Kurt Goldstein) and was formalised at the University of Wisconsin in the 1940s. From the 1960s onward, especially after Brenda Milner's work linking poor performance to frontal-lobe damage, it became one of the most widely used tests in clinical neuropsychology and is now also a staple of brain-training apps.",creator:"Published in 1948 in the Journal of Experimental Psychology by David A. Grant and Esta A. Berg at the University of Wisconsin; the design grew out of Berg's earlier master's work. It draws on an older European tradition of concept-formation and sorting tasks rather than being invented from nothing.",methods:"Treat every wrong answer as information, not failure: it tells you the current rule is not the one you are using, so switch deliberately rather than guessing randomly. Form an explicit hypothesis (\"it's colour now\"), test it, and the instant feedback contradicts you, abandon it fast \u2014 chasing a dead rule is the costliest mistake. Stay calm right after a rule flips; that is exactly where most errors cluster.",duration:"Short and regular beats long and rare: 5 to 10 minutes a session, a few times a week, is plenty. Stop when you notice attention slipping, since fatigue produces exactly the rigid, repetitive errors the task is meant to reduce.",research:"Evidence is strongest for what you would expect \u2014 you get better at this task and at closely related sorting and switching tasks, and it remains a clinically validated, sensitive marker of executive and frontal-lobe dysfunction. But it is sensitive, not specific: weak performance can stem from attention or memory rather than flexibility alone, its test-retest reliability is only moderate, and the bigger promises \u2014 that training it lifts general intelligence or broadly transfers to everyday decision-making \u2014 are largely unproven. Treat those grand claims with caution.",rec:"Slow down for one beat right after the rule changes \u2014 that single pause prevents most perseverative errors.",faq:[["Why does the rule keep changing without telling me?","That hidden change is the whole point. The task measures how quickly you notice the old rule has failed and switch to a new one, so an announced rule would remove exactly the skill being trained."],["I keep sorting by the same feature even after it's wrong \u2014 is that bad?","Repeating a rule after it stops working is called a perseverative error, and it is the single most informative signal here. Noticing and breaking that loop is the skill itself, so catching yourself doing it is real progress."],["Will this make me smarter or better at decisions in general?","Honestly, probably not in a broad way. You will reliably get better at sorting and rule-switching tasks, but solid evidence that it raises general intelligence or transfers to everyday choices is lacking, so train it because the skill is useful, not for an IQ boost."]],variants:"Versions differ in the number of cards, whether the rule shifts on a fixed schedule or unpredictably, and how much feedback you get. Modified short forms (such as the 48-card Nelson version) drop ambiguous cards, computerised editions add timing and reaction-speed measures, and child-friendly variants like the Dimensional Change Card Sort simplify the rules for younger players."},es:{about:"WCST: Reglas es una tarea de clasificaci\xf3n de cartas basada en el Test de Clasificaci\xf3n de Cartas de Wisconsin. Emparejas cada carta con una de varias cartas de referencia, pero nunca te dicen cu\xe1l es la regla de emparejamiento (color, forma o n\xfamero): la deduces a partir de un simple acierto o error tras cada movimiento, y en cuanto la tienes resuelta la regla cambia en silencio y tienes que dar con la nueva.",benefit:"Entrena la flexibilidad cognitiva y el cambio de conjunto: la capacidad de soltar una regla que acaba de dejar de funcionar y pasar a una nueva sin quedarte atascado. Por el camino ejercita el aprendizaje basado en la retroalimentaci\xf3n, la memoria de trabajo y la inhibici\xf3n necesaria para dejar de repetir un h\xe1bito.",history:"La tarea surgi\xf3 de los estudios europeos sobre la formaci\xf3n de conceptos y la clasificaci\xf3n (Narziss Ach, Kurt Goldstein) y se formaliz\xf3 en la Universidad de Wisconsin en los a\xf1os cuarenta. A partir de los a\xf1os sesenta, sobre todo tras el trabajo de Brenda Milner que vincul\xf3 el bajo rendimiento con el da\xf1o en el l\xf3bulo frontal, se convirti\xf3 en una de las pruebas m\xe1s utilizadas de la neuropsicolog\xeda cl\xednica y hoy es tambi\xe9n un cl\xe1sico de las aplicaciones de entrenamiento cerebral.",creator:"Publicado en 1948 en el Journal of Experimental Psychology por David A. Grant y Esta A. Berg en la Universidad de Wisconsin; el dise\xf1o creci\xf3 a partir del trabajo de m\xe1ster previo de Berg. Se apoya en una tradici\xf3n europea m\xe1s antigua de tareas de formaci\xf3n de conceptos y clasificaci\xf3n, en lugar de haber sido inventado de la nada.",methods:"Trata cada respuesta equivocada como informaci\xf3n, no como fracaso: te dice que la regla vigente no es la que est\xe1s usando, as\xed que cambia de forma deliberada en vez de adivinar al azar. Formula una hip\xf3tesis expl\xedcita (\"ahora es el color\"), ponla a prueba, y en cuanto la retroalimentaci\xf3n te contradiga, aband\xf3nala r\xe1pido: perseguir una regla muerta es el error m\xe1s caro. Mant\xe9n la calma justo despu\xe9s de que cambie una regla; ah\xed es exactamente donde se concentran la mayor\xeda de los errores.",duration:"Corto y regular gana a largo y espor\xe1dico: 5 a 10 minutos por sesi\xf3n, unas cuantas veces por semana, es m\xe1s que suficiente. Para en cuanto notes que la atenci\xf3n se te escapa, ya que la fatiga produce justamente los errores r\xedgidos y repetitivos que la tarea pretende reducir.",research:"La evidencia es m\xe1s s\xf3lida para lo esperable: mejoras en esta tarea y en tareas de clasificaci\xf3n y cambio estrechamente relacionadas, y sigue siendo un marcador cl\xednicamente validado y sensible de la disfunci\xf3n ejecutiva y del l\xf3bulo frontal. Pero es sensible, no espec\xedfico: un rendimiento flojo puede deberse a la atenci\xf3n o a la memoria y no solo a la flexibilidad, su fiabilidad test-retest es apenas moderada, y las promesas mayores (que entrenarlo eleva la inteligencia general o se transfiere ampliamente a la toma de decisiones cotidiana) est\xe1n en gran medida sin demostrar. Toma esas grandes afirmaciones con cautela.",rec:"Frena un instante justo despu\xe9s de que cambie la regla: esa \xfanica pausa evita la mayor\xeda de los errores perseverativos.",faq:[["\xbfPor qu\xe9 la regla cambia una y otra vez sin avisarme?","Ese cambio oculto es justamente el objetivo. La tarea mide con qu\xe9 rapidez te das cuenta de que la regla antigua ha fallado y pasas a una nueva, as\xed que una regla anunciada eliminar\xeda exactamente la destreza que se est\xe1 entrenando."],["Sigo clasificando por la misma caracter\xedstica incluso cuando est\xe1 mal. \xbfEs eso malo?","Repetir una regla despu\xe9s de que deja de funcionar se llama error perseverativo, y es la se\xf1al m\xe1s informativa de todas aqu\xed. Notar y romper ese bucle es la destreza en s\xed, as\xed que pillarte haci\xe9ndolo es un progreso real."],["\xbfEsto me har\xe1 m\xe1s inteligente o mejor en las decisiones en general?","Sinceramente, seguramente no de forma amplia. Mejorar\xe1s de manera fiable en las tareas de clasificaci\xf3n y cambio de regla, pero falta evidencia s\xf3lida de que eleve la inteligencia general o se transfiera a las decisiones cotidianas, as\xed que entr\xe9nalo porque la destreza es \xfatil, no por un aumento del coeficiente intelectual."]],variants:"Las versiones difieren en el n\xfamero de cartas, en si la regla cambia seg\xfan un calendario fijo o de forma impredecible, y en cu\xe1nta retroalimentaci\xf3n recibes. Las formas cortas modificadas (como la versi\xf3n Nelson de 48 cartas) eliminan las cartas ambiguas, las ediciones informatizadas a\xf1aden medidas de cronometraje y velocidad de reacci\xf3n, y las variantes adaptadas a ni\xf1os, como el Dimensional Change Card Sort, simplifican las reglas para los jugadores m\xe1s peque\xf1os."},de:{about:"WCST: Rules ist eine Kartensortier-Aufgabe, die auf dem Wisconsin Card Sorting Test aufbaut. Du ordnest jede Karte einer von mehreren Vorlagekarten zu, doch die Sortierregel (Farbe, Form oder Anzahl) wird dir nie genannt \u2013 du erschlie\xdft sie aus einem schlichten richtig oder falsch nach jedem Zug, und in dem Moment, in dem du sie herausgefunden hast, \xe4ndert sich die Regel stillschweigend und du musst die neue finden.",benefit:"Trainiert werden die kognitive Flexibilit\xe4t und das Set-Shifting: die F\xe4higkeit, eine Regel fallen zu lassen, die gerade aufgeh\xf6rt hat zu funktionieren, und ohne h\xe4ngenzubleiben zu einer neuen zu wechseln. Nebenbei werden das Lernen aus R\xfcckmeldung, das Arbeitsged\xe4chtnis und die Hemmung ge\xfcbt, die n\xf6tig ist, um eine Gewohnheit nicht zu wiederholen.",history:"Die Aufgabe entstand aus europ\xe4ischen Untersuchungen zur Begriffsbildung und zum Sortieren (Narziss Ach, Kurt Goldstein) und wurde in den 1940er-Jahren an der University of Wisconsin formalisiert. Ab den 1960er-Jahren, besonders nach Brenda Milners Arbeit, die schwache Leistungen mit Sch\xe4den des Stirnlappens in Verbindung brachte, wurde sie zu einem der am h\xe4ufigsten genutzten Tests der klinischen Neuropsychologie und ist heute auch ein fester Bestandteil von Gehirntrainings-Apps.",creator:"Ver\xf6ffentlicht 1948 im Journal of Experimental Psychology von David A. Grant und Esta A. Berg an der University of Wisconsin; das Design ging aus Bergs fr\xfcherer Masterarbeit hervor. Es sch\xf6pft aus einer \xe4lteren europ\xe4ischen Tradition von Begriffsbildungs- und Sortieraufgaben, statt aus dem Nichts erfunden worden zu sein.",methods:"Behandle jede falsche Antwort als Information, nicht als Versagen: Sie sagt dir, dass die aktuelle Regel nicht die ist, die du gerade benutzt, also wechsle bewusst, statt blind zu raten. Bilde eine ausdr\xfcckliche Hypothese (\"jetzt ist es die Farbe\"), pr\xfcfe sie, und in dem Augenblick, in dem die R\xfcckmeldung dir widerspricht, lass sie schnell fallen \u2013 einer toten Regel hinterherzujagen ist der teuerste Fehler. Bleib direkt nach einem Regelwechsel ruhig; genau dort h\xe4ufen sich die meisten Fehler.",duration:"Kurz und regelm\xe4\xdfig schl\xe4gt lang und selten: 5 bis 10 Minuten pro Sitzung, ein paar Mal die Woche, reichen v\xf6llig. H\xf6r auf, sobald du merkst, dass die Aufmerksamkeit nachl\xe4sst, denn Erm\xfcdung erzeugt genau die starren, wiederholten Fehler, die die Aufgabe verringern soll.",research:"Am st\xe4rksten belegt ist das Erwartbare \u2013 du wirst in dieser Aufgabe und bei eng verwandten Sortier- und Wechselaufgaben besser, und sie bleibt ein klinisch validierter, empfindlicher Marker f\xfcr exekutive und stirnhirnbezogene Funktionsst\xf6rungen. Doch sie ist empfindlich, nicht spezifisch: Schwache Leistungen k\xf6nnen ebenso von Aufmerksamkeit oder Ged\xe4chtnis herr\xfchren wie von der Flexibilit\xe4t allein, ihre Retest-Reliabilit\xe4t ist nur m\xe4\xdfig, und die gr\xf6\xdferen Versprechen \u2013 dass ihr Training die allgemeine Intelligenz hebt oder sich breit auf das allt\xe4gliche Entscheiden \xfcbertr\xe4gt \u2013 sind weitgehend unbelegt. Behandle diese gro\xdfen Behauptungen mit Vorsicht.",rec:"Halte direkt nach dem Regelwechsel einen Moment inne \u2013 diese eine Pause verhindert die meisten perseverativen Fehler.",faq:[["Warum wechselt die Regel st\xe4ndig, ohne mir Bescheid zu geben?","Dieser verborgene Wechsel ist der ganze Sinn. Die Aufgabe misst, wie schnell du bemerkst, dass die alte Regel versagt hat, und zu einer neuen wechselst, eine angek\xfcndigte Regel w\xfcrde also genau die F\xe4higkeit entfernen, die trainiert wird."],["Ich sortiere st\xe4ndig nach demselben Merkmal, auch wenn es falsch ist \u2013 ist das schlimm?","Eine Regel zu wiederholen, nachdem sie aufgeh\xf6rt hat zu funktionieren, nennt man einen perseverativen Fehler, und das ist hier das aufschlussreichste Signal \xfcberhaupt. Diese Schleife zu bemerken und zu durchbrechen ist die F\xe4higkeit selbst, sich dabei zu ertappen ist also echter Fortschritt."],["Werde ich dadurch kl\xfcger oder allgemein besser im Entscheiden?","Ehrlich gesagt wohl nicht in einem breiten Sinn. Du wirst zuverl\xe4ssig besser bei Sortier- und Regelwechselaufgaben, aber solide Belege daf\xfcr, dass es die allgemeine Intelligenz hebt oder sich auf allt\xe4gliche Entscheidungen \xfcbertr\xe4gt, fehlen. Trainiere es also, weil die F\xe4higkeit n\xfctzlich ist, nicht f\xfcr einen IQ-Schub."]],variants:"Die Versionen unterscheiden sich in der Zahl der Karten, darin, ob die Regel nach festem Schema oder unvorhersehbar wechselt, und wie viel R\xfcckmeldung du erh\xe4ltst. Modifizierte Kurzformen (etwa die 48-Karten-Version nach Nelson) lassen mehrdeutige Karten weg, computergest\xfctzte Ausgaben f\xfcgen Zeit- und Reaktionsma\xdfe hinzu, und kindgerechte Varianten wie der Dimensional Change Card Sort vereinfachen die Regeln f\xfcr j\xfcngere Spielende."},pt:{about:"WCST: Regras \xe9 uma tarefa de classifica\xe7\xe3o de cartas baseada no Teste de Classifica\xe7\xe3o de Cartas de Wisconsin. Voc\xea combina cada carta com uma de v\xe1rias cartas de refer\xeancia, mas nunca te dizem qual \xe9 a regra de combina\xe7\xe3o (cor, forma ou n\xfamero) \u2014 voc\xea a deduz a partir de um simples certo ou errado depois de cada jogada, e no instante em que voc\xea a descobre a regra muda em sil\xeancio e voc\xea precisa achar a nova.",benefit:"Treina a flexibilidade cognitiva e a troca de conjunto: a capacidade de largar uma regra que acabou de parar de funcionar e mudar para uma nova sem travar. No caminho, exercita a aprendizagem baseada em feedback, a mem\xf3ria de trabalho e a inibi\xe7\xe3o necess\xe1ria para parar de repetir um h\xe1bito.",history:"A tarefa surgiu a partir de estudos europeus sobre forma\xe7\xe3o de conceitos e classifica\xe7\xe3o (Narziss Ach, Kurt Goldstein) e foi formalizada na Universidade de Wisconsin na d\xe9cada de 1940. A partir dos anos 1960, sobretudo depois do trabalho de Brenda Milner ligando o baixo desempenho a les\xf5es do lobo frontal, tornou-se um dos testes mais usados na neuropsicologia cl\xednica e hoje tamb\xe9m \xe9 presen\xe7a constante em aplicativos de treino cerebral.",creator:"Publicado em 1948 no Journal of Experimental Psychology por David A. Grant e Esta A. Berg, na Universidade de Wisconsin; o desenho cresceu a partir do trabalho de mestrado anterior de Berg. Apoia-se numa tradi\xe7\xe3o europeia mais antiga de tarefas de forma\xe7\xe3o de conceitos e classifica\xe7\xe3o, em vez de ter sido inventado do nada.",methods:"Trate cada resposta errada como informa\xe7\xe3o, n\xe3o como fracasso: ela te diz que a regra atual n\xe3o \xe9 a que voc\xea est\xe1 usando, ent\xe3o mude de forma deliberada em vez de chutar ao acaso. Formule uma hip\xf3tese expl\xedcita (\"agora \xe9 cor\"), teste-a, e no instante em que o feedback te contradisser, abandone-a r\xe1pido \u2014 perseguir uma regra morta \xe9 o erro mais caro. Mantenha a calma logo depois que uma regra vira; \xe9 justamente a\xed que a maioria dos erros se concentra.",duration:"Curto e regular vence longo e espor\xe1dico: 5 a 10 minutos por sess\xe3o, algumas vezes por semana, j\xe1 basta. Pare quando perceber a aten\xe7\xe3o escapando, j\xe1 que o cansa\xe7o produz exatamente os erros r\xedgidos e repetitivos que a tarefa busca reduzir.",research:"A evid\xeancia \xe9 mais forte para o que se espera \u2014 voc\xea melhora nesta tarefa e em tarefas de classifica\xe7\xe3o e troca bem pr\xf3ximas, e ela continua sendo um marcador clinicamente validado e sens\xedvel de disfun\xe7\xe3o executiva e do lobo frontal. Mas \xe9 sens\xedvel, n\xe3o espec\xedfica: o desempenho fraco pode vir da aten\xe7\xe3o ou da mem\xf3ria, e n\xe3o s\xf3 da flexibilidade, a sua confiabilidade teste-reteste \xe9 apenas moderada, e as promessas maiores \u2014 de que trein\xe1-la eleva a intelig\xeancia geral ou se transfere amplamente para a tomada de decis\xe3o do dia a dia \u2014 s\xe3o em grande parte n\xe3o comprovadas. Encare essas afirma\xe7\xf5es grandiosas com cautela.",rec:"Desacelere por um instante logo depois que a regra muda \u2014 essa \xfanica pausa evita a maioria dos erros perseverativos.",faq:[["Por que a regra fica mudando sem me avisar?","Essa mudan\xe7a oculta \xe9 justamente o ponto. A tarefa mede a rapidez com que voc\xea percebe que a regra antiga falhou e muda para uma nova, ent\xe3o uma regra anunciada removeria exatamente a habilidade que est\xe1 sendo treinada."],["Eu continuo classificando pela mesma caracter\xedstica mesmo depois de errar \u2014 isso \xe9 ruim?","Repetir uma regra depois que ela parou de funcionar \xe9 chamado de erro perseverativo, e \xe9 o sinal mais informativo aqui. Perceber e quebrar esse ciclo \xe9 a pr\xf3pria habilidade, ent\xe3o te flagrar fazendo isso \xe9 um progresso real."],["Isso vai me deixar mais inteligente ou melhor em decis\xf5es de modo geral?","Sinceramente, provavelmente n\xe3o de forma ampla. Voc\xea vai melhorar de modo confi\xe1vel em tarefas de classifica\xe7\xe3o e troca de regras, mas falta evid\xeancia s\xf3lida de que isso eleve a intelig\xeancia geral ou se transfira para escolhas do dia a dia, ent\xe3o treine porque a habilidade \xe9 \xfatil, n\xe3o em busca de um aumento de QI."]],variants:"As vers\xf5es diferem no n\xfamero de cartas, em se a regra muda numa programa\xe7\xe3o fixa ou de forma imprevis\xedvel, e em quanto feedback voc\xea recebe. Formas curtas modificadas (como a vers\xe3o Nelson de 48 cartas) descartam cartas amb\xedguas, as edi\xe7\xf5es computadorizadas acrescentam medidas de tempo e velocidade de rea\xe7\xe3o, e variantes amig\xe1veis para crian\xe7as, como o Dimensional Change Card Sort, simplificam as regras para jogadores mais novos."},hi:{about:"WCST: Rules \u090f\u0915 \u0915\u093e\u0930\u094d\u0921-\u091b\u0901\u091f\u093e\u0908 \u091f\u093e\u0938\u094d\u0915 \u0939\u0948, \u091c\u094b Wisconsin Card Sorting Test \u092a\u0930 \u0906\u0927\u093e\u0930\u093f\u0924 \u0939\u0948\u0964 \u0906\u092a \u0939\u0930 \u0915\u093e\u0930\u094d\u0921 \u0915\u094b \u0915\u0908 \u0938\u0902\u0926\u0930\u094d\u092d-\u0915\u093e\u0930\u094d\u0921\u094b\u0902 \u092e\u0947\u0902 \u0938\u0947 \u0915\u093f\u0938\u0940 \u090f\u0915 \u0938\u0947 \u092e\u093f\u0932\u093e\u0924\u0947 \u0939\u0948\u0902, \u092a\u0930 \u092e\u093f\u0932\u093e\u0928 \u0915\u093e \u0928\u093f\u092f\u092e (\u0930\u0902\u0917, \u0906\u0915\u093e\u0930, \u092f\u093e \u0938\u0902\u0916\u094d\u092f\u093e) \u0906\u092a\u0915\u094b \u0915\u092d\u0940 \u0928\u0939\u0940\u0902 \u092c\u0924\u093e\u092f\u093e \u091c\u093e\u0924\u093e \u2014 \u0906\u092a \u0939\u0930 \u091a\u093e\u0932 \u0915\u0947 \u092c\u093e\u0926 \u092c\u0938 \u0938\u0939\u0940 \u092f\u093e \u0917\u093c\u0932\u0924 \u0938\u0947 \u0909\u0938\u0915\u093e \u0905\u0902\u0926\u093e\u091c\u093c\u093e \u0932\u0917\u093e\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u091c\u093f\u0938 \u092a\u0932 \u0906\u092a \u0909\u0938\u0947 \u0938\u092e\u091d \u0932\u0947\u0924\u0947 \u0939\u0948\u0902, \u0928\u093f\u092f\u092e \u091a\u0941\u092a\u091a\u093e\u092a \u092c\u0926\u0932 \u091c\u093e\u0924\u093e \u0939\u0948 \u0914\u0930 \u0906\u092a\u0915\u094b \u0928\u092f\u093e \u0922\u0942\u0901\u0922\u0928\u093e \u092a\u0921\u093c\u0924\u093e \u0939\u0948\u0964",benefit:"\u092f\u0939 \u0938\u0902\u091c\u094d\u091e\u093e\u0928\u093e\u0924\u094d\u092e\u0915 \u0932\u091a\u0940\u0932\u093e\u092a\u0928 \u0914\u0930 set-shifting \u0938\u093e\u0927\u0924\u093e \u0939\u0948: \u0909\u0938 \u0928\u093f\u092f\u092e \u0915\u094b \u091b\u094b\u0921\u093c \u0926\u0947\u0928\u0947 \u0915\u0940 \u0915\u094d\u0937\u092e\u0924\u093e \u091c\u094b \u0905\u092d\u0940-\u0905\u092d\u0940 \u0915\u093e\u092e \u0915\u0930\u0928\u093e \u092c\u0902\u0926 \u0915\u0930 \u091a\u0941\u0915\u093e \u0939\u0948, \u0914\u0930 \u092c\u093f\u0928\u093e \u0905\u091f\u0915\u0947 \u0915\u093f\u0938\u0940 \u0928\u090f \u092a\u0930 switch \u0915\u0930 \u091c\u093e\u0928\u093e\u0964 \u0907\u0938 \u0926\u094c\u0930\u093e\u0928 \u092f\u0939 \u092b\u093c\u0940\u0921\u092c\u0948\u0915-\u0906\u0927\u093e\u0930\u093f\u0924 \u0938\u0940\u0916\u0928\u093e, \u0915\u093e\u0930\u094d\u092f\u0936\u0940\u0932 \u0938\u094d\u092e\u0943\u0924\u093f (working memory), \u0914\u0930 \u0915\u093f\u0938\u0940 \u0906\u0926\u0924 \u0915\u094b \u0926\u094b\u0939\u0930\u093e\u0928\u093e \u0930\u094b\u0915\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u091c\u093c\u0930\u0942\u0930\u0940 \u0928\u093f\u0930\u094b\u0927 (inhibition) \u0915\u0940 \u092d\u0940 \u0915\u0938\u0930\u0924 \u0915\u0930\u093e\u0924\u093e \u0939\u0948\u0964",history:"\u092f\u0939 \u091f\u093e\u0938\u094d\u0915 \u0905\u0935\u0927\u093e\u0930\u0923\u093e-\u0928\u093f\u0930\u094d\u092e\u093e\u0923 \u0914\u0930 \u091b\u0901\u091f\u093e\u0908 \u0915\u0947 \u092f\u0942\u0930\u094b\u092a\u0940\u092f \u0905\u0927\u094d\u092f\u092f\u0928\u094b\u0902 (Narziss Ach, Kurt Goldstein) \u0938\u0947 \u0928\u093f\u0915\u0932\u093e \u0914\u0930 1940 \u0915\u0947 \u0926\u0936\u0915 \u092e\u0947\u0902 University of Wisconsin \u092e\u0947\u0902 \u0914\u092a\u091a\u093e\u0930\u093f\u0915 \u0930\u0942\u092a \u092a\u093e\u092f\u093e\u0964 1960 \u0915\u0947 \u0926\u0936\u0915 \u0938\u0947 \u0906\u0917\u0947, \u0916\u093c\u093e\u0938\u0915\u0930 Brenda Milner \u0915\u0947 \u0909\u0938 \u0915\u093e\u092e \u0915\u0947 \u092c\u093e\u0926 \u091c\u093f\u0938\u0928\u0947 \u0915\u092e\u091c\u093c\u094b\u0930 \u092a\u094d\u0930\u0926\u0930\u094d\u0936\u0928 \u0915\u094b \u092b\u093c\u094d\u0930\u0902\u091f\u0932-\u0932\u094b\u092c \u0915\u094d\u0937\u0924\u093f \u0938\u0947 \u091c\u094b\u0921\u093c\u093e, \u092f\u0939 \u0915\u094d\u0932\u093f\u0928\u093f\u0915\u0932 \u0928\u094d\u092f\u0942\u0930\u094b\u0938\u093e\u0907\u0915\u094b\u0932\u0949\u091c\u0940 \u0915\u0947 \u0938\u092c\u0938\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0939\u094b\u0928\u0947 \u0935\u093e\u0932\u0947 \u091f\u0947\u0938\u094d\u091f\u094b\u0902 \u092e\u0947\u0902 \u0938\u0947 \u090f\u0915 \u092c\u0928 \u0917\u092f\u093e, \u0914\u0930 \u0905\u092c \u092c\u094d\u0930\u0947\u0928-\u091f\u094d\u0930\u0947\u0928\u093f\u0902\u0917 \u0910\u092a\u094d\u0938 \u0915\u093e \u092d\u0940 \u090f\u0915 \u0928\u093f\u092f\u092e\u093f\u0924 \u0939\u093f\u0938\u094d\u0938\u093e \u0939\u0948\u0964",creator:"\u0907\u0938\u0947 1948 \u092e\u0947\u0902 Journal of Experimental Psychology \u092e\u0947\u0902 University of Wisconsin \u0915\u0947 David A. Grant \u0914\u0930 Esta A. Berg \u0928\u0947 \u092a\u094d\u0930\u0915\u093e\u0936\u093f\u0924 \u0915\u093f\u092f\u093e; \u0907\u0938\u0915\u093e \u0921\u093f\u091c\u093c\u093e\u0907\u0928 Berg \u0915\u0947 \u092a\u0939\u0932\u0947 \u0915\u0947 \u092e\u093e\u0938\u094d\u091f\u0930\u094d\u0938 \u0915\u093e\u0930\u094d\u092f \u0938\u0947 \u0909\u092a\u091c\u093e \u0925\u093e\u0964 \u092f\u0939 \u0936\u0942\u0928\u094d\u092f \u0938\u0947 \u0917\u0922\u093c\u093e \u0917\u092f\u093e \u0915\u0941\u091b \u0928\u0939\u0940\u0902, \u092c\u0932\u094d\u0915\u093f \u0905\u0935\u0927\u093e\u0930\u0923\u093e-\u0928\u093f\u0930\u094d\u092e\u093e\u0923 \u0914\u0930 \u091b\u0901\u091f\u093e\u0908 \u0915\u0947 \u0915\u093e\u0930\u094d\u092f\u094b\u0902 \u0915\u0940 \u090f\u0915 \u092a\u0941\u0930\u093e\u0928\u0940 \u092f\u0942\u0930\u094b\u092a\u0940\u092f \u092a\u0930\u0902\u092a\u0930\u093e \u092a\u0930 \u091f\u093f\u0915\u093e \u0939\u0948\u0964",methods:"\u0939\u0930 \u0917\u093c\u0932\u0924 \u091c\u0935\u093e\u092c \u0915\u094b \u0928\u093e\u0915\u093e\u092e\u0940 \u0928\u0939\u0940\u0902, \u092c\u0932\u094d\u0915\u093f \u091c\u093e\u0928\u0915\u093e\u0930\u0940 \u0938\u092e\u091d\u0947\u0902: \u0935\u0939 \u0906\u092a\u0915\u094b \u092c\u0924\u093e\u0924\u093e \u0939\u0948 \u0915\u093f \u092e\u094c\u091c\u0942\u0926\u093e \u0928\u093f\u092f\u092e \u0935\u0939 \u0928\u0939\u0940\u0902 \u0939\u0948 \u091c\u093f\u0938\u0947 \u0906\u092a \u0907\u0938\u094d\u0924\u0947\u092e\u093e\u0932 \u0915\u0930 \u0930\u0939\u0947 \u0939\u0948\u0902, \u0907\u0938\u0932\u093f\u090f \u092c\u0947\u0924\u0930\u0924\u0940\u092c \u0905\u0902\u0926\u093e\u091c\u093c\u093e \u0932\u0917\u093e\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u0938\u094b\u091a-\u0938\u092e\u091d\u0915\u0930 switch \u0915\u0930\u0947\u0902\u0964 \u090f\u0915 \u0938\u093e\u092b\u093c \u092a\u0930\u093f\u0915\u0932\u094d\u092a\u0928\u093e \u092c\u0928\u093e\u090f\u0901 (\"\u0905\u092c \u092f\u0939 \u0930\u0902\u0917 \u0939\u0948\"), \u0909\u0938\u0947 \u091c\u093e\u0901\u091a\u0947\u0902, \u0914\u0930 \u091c\u093f\u0938 \u092a\u0932 \u092b\u093c\u0940\u0921\u092c\u0948\u0915 \u0909\u0938\u0947 \u0917\u093c\u0932\u0924 \u0920\u0939\u0930\u093e\u090f, \u0909\u0938\u0947 \u092b\u093c\u094c\u0930\u0928 \u091b\u094b\u0921\u093c \u0926\u0947\u0902 \u2014 \u0915\u093f\u0938\u0940 \u092e\u0930\u0947 \u0939\u0941\u090f \u0928\u093f\u092f\u092e \u0915\u0947 \u092a\u0940\u091b\u0947 \u092d\u093e\u0917\u0928\u093e \u0939\u0940 \u0938\u092c\u0938\u0947 \u092e\u0939\u0901\u0917\u0940 \u0917\u093c\u0932\u0924\u0940 \u0939\u0948\u0964 \u0928\u093f\u092f\u092e \u092a\u0932\u091f\u0928\u0947 \u0915\u0947 \u0924\u0941\u0930\u0902\u0924 \u092c\u093e\u0926 \u0936\u093e\u0902\u0924 \u0930\u0939\u0947\u0902; \u0920\u0940\u0915 \u0935\u0939\u0940\u0902 \u091c\u093c\u094d\u092f\u093e\u0926\u093e\u0924\u0930 \u0917\u093c\u0932\u0924\u093f\u092f\u093e\u0901 \u091c\u092e\u093e \u0939\u094b\u0924\u0940 \u0939\u0948\u0902\u0964",duration:"\u091b\u094b\u091f\u093e \u0914\u0930 \u0928\u093f\u092f\u092e\u093f\u0924, \u0932\u0902\u092c\u0947-\u0914\u0930-\u0915\u092d\u0940-\u0915\u092d\u093e\u0930 \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u0939\u0948: \u090f\u0915 \u0938\u0924\u094d\u0930 \u092e\u0947\u0902 5 \u0938\u0947 10 \u092e\u093f\u0928\u091f, \u0939\u092b\u093c\u094d\u0924\u0947 \u092e\u0947\u0902 \u0915\u0941\u091b \u092c\u093e\u0930, \u0915\u093e\u092b\u093c\u0940 \u0939\u0948\u0902\u0964 \u091c\u0948\u0938\u0947 \u0939\u0940 \u0927\u094d\u092f\u093e\u0928 \u092b\u093f\u0938\u0932\u0924\u093e \u092e\u0939\u0938\u0942\u0938 \u0939\u094b, \u0930\u0941\u0915 \u091c\u093e\u090f\u0901, \u0915\u094d\u092f\u094b\u0902\u0915\u093f \u0925\u0915\u093e\u0928 \u0920\u0940\u0915 \u0935\u0939\u0940 \u091c\u0921\u093c, \u0926\u094b\u0939\u0930\u093e\u0935 \u0935\u093e\u0932\u0940 \u0917\u093c\u0932\u0924\u093f\u092f\u093e\u0901 \u092a\u0948\u0926\u093e \u0915\u0930\u0924\u0940 \u0939\u0948 \u091c\u093f\u0928\u094d\u0939\u0947\u0902 \u092f\u0939 \u091f\u093e\u0938\u094d\u0915 \u0918\u091f\u093e\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u092c\u0928\u093e \u0939\u0948\u0964",research:"\u0938\u092c\u0938\u0947 \u092a\u0941\u0916\u093c\u094d\u0924\u093e \u0938\u092c\u0942\u0924 \u0935\u0939\u0940 \u0939\u0948\u0902 \u091c\u093f\u0928\u0915\u0940 \u0909\u092e\u094d\u092e\u0940\u0926 \u0939\u094b\u0917\u0940 \u2014 \u0906\u092a \u0907\u0938 \u091f\u093e\u0938\u094d\u0915 \u092e\u0947\u0902 \u0914\u0930 \u0907\u0938\u0938\u0947 \u0915\u093c\u0930\u0940\u092c\u0940 \u091b\u0901\u091f\u093e\u0908 \u0924\u0925\u093e switching \u0915\u093e\u0930\u094d\u092f\u094b\u0902 \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u092f\u0939 \u0915\u093e\u0930\u094d\u092f\u0915\u093e\u0930\u0940 \u0924\u0925\u093e \u092b\u093c\u094d\u0930\u0902\u091f\u0932-\u0932\u094b\u092c \u0935\u093f\u0915\u093e\u0930 \u0915\u093e \u090f\u0915 \u0915\u094d\u0932\u093f\u0928\u093f\u0915\u0932\u0940 \u0938\u0924\u094d\u092f\u093e\u092a\u093f\u0924, \u0938\u0902\u0935\u0947\u0926\u0928\u0936\u0940\u0932 \u0938\u0902\u0915\u0947\u0924\u0915 \u092c\u0928\u093e \u0939\u0941\u0906 \u0939\u0948\u0964 \u092a\u0930 \u092f\u0939 \u0938\u0902\u0935\u0947\u0926\u0928\u0936\u0940\u0932 \u0939\u0948, \u0935\u093f\u0936\u093f\u0937\u094d\u091f \u0928\u0939\u0940\u0902: \u0915\u092e\u091c\u093c\u094b\u0930 \u092a\u094d\u0930\u0926\u0930\u094d\u0936\u0928 \u0915\u0940 \u091c\u0921\u093c \u0905\u0915\u0947\u0932\u0947 \u0932\u091a\u0940\u0932\u0947\u092a\u0928 \u0915\u0947 \u092c\u091c\u093e\u092f \u0927\u094d\u092f\u093e\u0928 \u092f\u093e \u0938\u094d\u092e\u0943\u0924\u093f \u092d\u0940 \u0939\u094b \u0938\u0915\u0924\u0940 \u0939\u0948, \u0907\u0938\u0915\u0940 test-retest \u0935\u093f\u0936\u094d\u0935\u0938\u0928\u0940\u092f\u0924\u093e \u092c\u0938 \u092e\u0927\u094d\u092f\u092e \u0939\u0948, \u0914\u0930 \u092c\u0921\u093c\u0947 \u0935\u093e\u0926\u0947 \u2014 \u0915\u093f \u0907\u0938\u0915\u093e \u092a\u094d\u0930\u0936\u093f\u0915\u094d\u0937\u0923 \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u092c\u0941\u0926\u094d\u0927\u093f \u092c\u0922\u093c\u093e\u0924\u093e \u0939\u0948 \u092f\u093e \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0947 \u0928\u093f\u0930\u094d\u0923\u092f\u094b\u0902 \u0924\u0915 \u0935\u094d\u092f\u093e\u092a\u0915 \u0930\u0942\u092a \u0938\u0947 \u092a\u0939\u0941\u0901\u091a\u0924\u093e \u0939\u0948 \u2014 \u0915\u093e\u092b\u093c\u0940 \u0939\u0926 \u0924\u0915 \u0905\u0938\u093f\u0926\u094d\u0927 \u0939\u0948\u0902\u0964 \u0909\u0928 \u092d\u093e\u0930\u0940-\u092d\u0930\u0915\u092e \u0926\u093e\u0935\u094b\u0902 \u0915\u094b \u0938\u093e\u0935\u0927\u093e\u0928\u0940 \u0938\u0947 \u0932\u0947\u0902\u0964",rec:"\u0928\u093f\u092f\u092e \u092c\u0926\u0932\u0928\u0947 \u0915\u0947 \u0920\u0940\u0915 \u092c\u093e\u0926 \u090f\u0915 \u092a\u0932 \u0915\u0947 \u0932\u093f\u090f \u0927\u0940\u092e\u0947 \u0939\u094b \u091c\u093e\u090f\u0901 \u2014 \u0935\u0939\u0940 \u090f\u0915 \u0920\u0939\u0930\u093e\u0935 \u091c\u093c\u094d\u092f\u093e\u0926\u093e\u0924\u0930 perseverative (\u0905\u0921\u093c\u093f\u092f\u0932) \u0917\u093c\u0932\u0924\u093f\u092f\u093e\u0901 \u0930\u094b\u0915 \u0926\u0947\u0924\u093e \u0939\u0948\u0964",faq:[["\u0928\u093f\u092f\u092e \u092e\u0941\u091d\u0947 \u092c\u0924\u093e\u090f \u092c\u093f\u0928\u093e \u092c\u093e\u0930-\u092c\u093e\u0930 \u0915\u094d\u092f\u094b\u0902 \u092c\u0926\u0932\u0924\u093e \u0930\u0939\u0924\u093e \u0939\u0948?","\u0935\u0939 \u091b\u093f\u092a\u093e \u0939\u0941\u0906 \u092c\u0926\u0932\u093e\u0935 \u0939\u0940 \u092a\u0942\u0930\u093e \u092e\u0915\u093c\u0938\u0926 \u0939\u0948\u0964 \u092f\u0939 \u091f\u093e\u0938\u094d\u0915 \u092e\u093e\u092a\u0924\u093e \u0939\u0948 \u0915\u093f \u0906\u092a \u0915\u093f\u0924\u0928\u0940 \u091c\u0932\u094d\u0926\u0940 \u092d\u093e\u0901\u092a \u0932\u0947\u0924\u0947 \u0939\u0948\u0902 \u0915\u093f \u092a\u0941\u0930\u093e\u0928\u093e \u0928\u093f\u092f\u092e \u0928\u093e\u0915\u093e\u092e \u0939\u094b \u091a\u0941\u0915\u093e \u0939\u0948 \u0914\u0930 \u0915\u093f\u0938\u0940 \u0928\u090f \u092a\u0930 switch \u0915\u0930\u0924\u0947 \u0939\u0948\u0902 \u2014 \u0907\u0938\u0932\u093f\u090f \u0918\u094b\u0937\u093f\u0924 \u0928\u093f\u092f\u092e \u0920\u0940\u0915 \u0909\u0938\u0940 \u0939\u0941\u0928\u0930 \u0915\u094b \u092e\u093f\u091f\u093e \u0926\u0947\u0924\u093e \u091c\u093f\u0938\u0947 \u0938\u093e\u0927\u093e \u091c\u093e \u0930\u0939\u093e \u0939\u0948\u0964"],["\u0917\u093c\u0932\u0924 \u0938\u093e\u092c\u093f\u0924 \u0939\u094b\u0928\u0947 \u0915\u0947 \u092c\u093e\u0926 \u092d\u0940 \u092e\u0948\u0902 \u0909\u0938\u0940 \u0935\u093f\u0936\u0947\u0937\u0924\u093e \u0938\u0947 \u091b\u093e\u0901\u091f\u0924\u093e \u0930\u0939\u0924\u093e \u0939\u0942\u0901 \u2014 \u0915\u094d\u092f\u093e \u092f\u0939 \u092c\u0941\u0930\u093e \u0939\u0948?","\u0915\u093f\u0938\u0940 \u0928\u093f\u092f\u092e \u0915\u0947 \u0915\u093e\u092e \u0915\u0930\u0928\u093e \u092c\u0902\u0926 \u0915\u0930 \u0926\u0947\u0928\u0947 \u0915\u0947 \u092c\u093e\u0926 \u092d\u0940 \u0909\u0938\u0947 \u0926\u094b\u0939\u0930\u093e\u0924\u0947 \u0930\u0939\u0928\u093e perseverative error (\u0905\u0921\u093c\u093f\u092f\u0932 \u0917\u093c\u0932\u0924\u0940) \u0915\u0939\u0932\u093e\u0924\u093e \u0939\u0948, \u0914\u0930 \u092f\u0939\u093e\u0901 \u092f\u0939\u0940 \u0938\u092c\u0938\u0947 \u091c\u093e\u0928\u0915\u093e\u0930\u0940 \u0926\u0947\u0928\u0947 \u0935\u093e\u0932\u093e \u0938\u0902\u0915\u0947\u0924 \u0939\u0948\u0964 \u0909\u0938 \u092b\u0902\u0926\u0947 \u0915\u094b \u092d\u093e\u0901\u092a\u0915\u0930 \u0924\u094b\u0921\u093c \u0926\u0947\u0928\u093e \u0939\u0940 \u0905\u0938\u0932\u0940 \u0939\u0941\u0928\u0930 \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0916\u093c\u0941\u0926 \u0915\u094b \u0910\u0938\u093e \u0915\u0930\u0924\u0947 \u092a\u0915\u0921\u093c \u0932\u0947\u0928\u093e \u0938\u091a\u092e\u0941\u091a \u092a\u094d\u0930\u0917\u0924\u093f \u0939\u0948\u0964"],["\u0915\u094d\u092f\u093e \u0907\u0938\u0938\u0947 \u092e\u0948\u0902 \u0906\u092e \u0924\u094c\u0930 \u092a\u0930 \u0939\u094b\u0936\u093f\u092f\u093e\u0930 \u092f\u093e \u0928\u093f\u0930\u094d\u0923\u092f \u0932\u0947\u0928\u0947 \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u090a\u0901\u0917\u093e?","\u0908\u092e\u093e\u0928\u0926\u093e\u0930\u0940 \u0938\u0947 \u0915\u0939\u0947\u0902 \u0924\u094b \u0936\u093e\u092f\u0926 \u0915\u093f\u0938\u0940 \u0935\u094d\u092f\u093e\u092a\u0915 \u0924\u0930\u0940\u0915\u093c\u0947 \u0938\u0947 \u0928\u0939\u0940\u0902\u0964 \u0906\u092a \u091b\u0901\u091f\u093e\u0908 \u0914\u0930 \u0928\u093f\u092f\u092e-\u092c\u0926\u0932\u0928\u0947 \u0935\u093e\u0932\u0947 \u0915\u093e\u0930\u094d\u092f\u094b\u0902 \u092e\u0947\u0902 \u0924\u094b \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0922\u0902\u0917 \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u090f\u0901\u0917\u0947, \u092a\u0930 \u0907\u0938\u0915\u093e \u0920\u094b\u0938 \u0938\u092c\u0942\u0924 \u0915\u092e \u0939\u0948 \u0915\u093f \u092f\u0939 \u0938\u093e\u092e\u093e\u0928\u094d\u092f \u092c\u0941\u0926\u094d\u0927\u093f \u092c\u0922\u093c\u093e\u0924\u093e \u0939\u0948 \u092f\u093e \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0947 \u092b\u093c\u0948\u0938\u0932\u094b\u0902 \u0924\u0915 \u092a\u0939\u0941\u0901\u091a\u0924\u093e \u0939\u0948 \u2014 \u0907\u0938\u0932\u093f\u090f \u0907\u0938\u0947 \u0907\u0938\u0932\u093f\u090f \u0938\u093e\u0927\u0947\u0902 \u0915\u093f \u0939\u0941\u0928\u0930 \u0909\u092a\u092f\u094b\u0917\u0940 \u0939\u0948, IQ \u092c\u0922\u093c\u093e\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0928\u0939\u0940\u0902\u0964"]],variants:"\u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0915\u093e\u0930\u094d\u0921\u094b\u0902 \u0915\u0940 \u0938\u0902\u0916\u094d\u092f\u093e \u092e\u0947\u0902, \u0907\u0938\u092e\u0947\u0902 \u0915\u093f \u0928\u093f\u092f\u092e \u0924\u092f \u0905\u0928\u0941\u0938\u0942\u091a\u0940 \u092a\u0930 \u092c\u0926\u0932\u0924\u093e \u0939\u0948 \u092f\u093e \u0905\u092a\u094d\u0930\u0924\u094d\u092f\u093e\u0936\u093f\u0924 \u0922\u0902\u0917 \u0938\u0947, \u0914\u0930 \u0907\u0938\u092e\u0947\u0902 \u0915\u093f \u0906\u092a\u0915\u094b \u0915\u093f\u0924\u0928\u093e \u092b\u093c\u0940\u0921\u092c\u0948\u0915 \u092e\u093f\u0932\u0924\u093e \u0939\u0948 \u2014 \u0907\u0928 \u0938\u092c\u092e\u0947\u0902 \u0905\u0932\u0917 \u0939\u094b\u0924\u0947 \u0939\u0948\u0902\u0964 \u0938\u0902\u0936\u094b\u0927\u093f\u0924 \u091b\u094b\u091f\u0947 \u0930\u0942\u092a (\u091c\u0948\u0938\u0947 48-\u0915\u093e\u0930\u094d\u0921 \u0935\u093e\u0932\u093e Nelson \u0938\u0902\u0938\u094d\u0915\u0930\u0923) \u0905\u0938\u094d\u092a\u0937\u094d\u091f \u0915\u093e\u0930\u094d\u0921 \u0939\u091f\u093e \u0926\u0947\u0924\u0947 \u0939\u0948\u0902, \u0915\u0902\u092a\u094d\u092f\u0942\u091f\u0930\u0940\u0915\u0943\u0924 \u0938\u0902\u0938\u094d\u0915\u0930\u0923 \u0938\u092e\u092f \u0914\u0930 \u092a\u094d\u0930\u0924\u093f\u0915\u094d\u0930\u093f\u092f\u093e-\u0917\u0924\u093f \u0915\u0947 \u092e\u093e\u092a \u091c\u094b\u0921\u093c \u0926\u0947\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 Dimensional Change Card Sort \u091c\u0948\u0938\u0947 \u092c\u091a\u094d\u091a\u094b\u0902 \u0915\u0947 \u0905\u0928\u0941\u0915\u0942\u0932 \u0930\u0942\u092a\u093e\u0902\u0924\u0930 \u091b\u094b\u091f\u0947 \u0916\u093f\u0932\u093e\u0921\u093c\u093f\u092f\u094b\u0902 \u0915\u0947 \u0932\u093f\u090f \u0928\u093f\u092f\u092e \u0906\u0938\u093e\u0928 \u0915\u0930 \u0926\u0947\u0924\u0947 \u0939\u0948\u0902\u0964"},zh:{about:"WCST\uff1a\u89c4\u5219\uff0c\u662f\u4e00\u9879\u5efa\u7acb\u5728\u5a01\u65af\u5eb7\u661f\u5361\u7247\u5206\u7c7b\u6d4b\u9a8c\u4e4b\u4e0a\u7684\u5361\u7247\u5206\u7c7b\u4efb\u52a1\u3002\u4f60\u8981\u628a\u6bcf\u5f20\u5361\u7247\u4e0e\u51e0\u5f20\u53c2\u8003\u5361\u4e4b\u4e00\u76f8\u5339\u914d\uff0c\u4f46\u4ece\u4e0d\u4f1a\u6709\u4eba\u544a\u8bc9\u4f60\u5339\u914d\u7684\u89c4\u5219\uff08\u989c\u8272\u3001\u5f62\u72b6\u8fd8\u662f\u6570\u91cf\uff09\u2014\u2014\u4f60\u53ea\u80fd\u4ece\u6bcf\u6b65\u4e4b\u540e\u7b80\u5355\u7684\u5bf9\u6216\u9519\u91cc\u53bb\u63a8\u65ad\uff0c\u800c\u5c31\u5728\u4f60\u521a\u6478\u6e05\u89c4\u5219\u7684\u90a3\u4e00\u523b\uff0c\u5b83\u4f1a\u6084\u65e0\u58f0\u606f\u5730\u6539\u53d8\uff0c\u4f60\u53c8\u5f97\u53bb\u627e\u65b0\u7684\u89c4\u5219\u3002",benefit:"\u5b83\u8bad\u7ec3\u8ba4\u77e5\u7075\u6d3b\u6027\u548c\u5b9a\u52bf\u8f6c\u6362\uff1a\u5728\u4e00\u6761\u89c4\u5219\u521a\u521a\u5931\u6548\u65f6\u628a\u5b83\u4e22\u6389\u3001\u6362\u5230\u4e00\u6761\u65b0\u89c4\u5219\u4e0a\u800c\u4e0d\u5361\u4f4f\u7684\u80fd\u529b\u3002\u5728\u8fd9\u4e2a\u8fc7\u7a0b\u4e2d\uff0c\u5b83\u8fd8\u953b\u70bc\u57fa\u4e8e\u53cd\u9988\u7684\u5b66\u4e60\u3001\u5de5\u4f5c\u8bb0\u5fc6\uff0c\u4ee5\u53ca\u505c\u6b62\u91cd\u590d\u67d0\u4e2a\u4e60\u60ef\u6240\u9700\u7684\u6291\u5236\u3002",history:"\u8fd9\u9879\u4efb\u52a1\u8131\u80ce\u4e8e\u6b27\u6d32\u5bf9\u6982\u5ff5\u5f62\u6210\u4e0e\u5206\u7c7b\u7684\u7814\u7a76\uff08Narziss Ach\u3001Kurt Goldstein\uff09\uff0c\u5e76\u5728 1940 \u5e74\u4ee3\u4e8e\u5a01\u65af\u5eb7\u661f\u5927\u5b66\u88ab\u5f62\u5f0f\u5316\u3002\u4ece 1960 \u5e74\u4ee3\u8d77\uff0c\u5c24\u5176\u662f\u5728 Brenda Milner \u628a\u8868\u73b0\u4e0d\u4f73\u4e0e\u989d\u53f6\u635f\u4f24\u8054\u7cfb\u8d77\u6765\u7684\u5de5\u4f5c\u4e4b\u540e\uff0c\u5b83\u6210\u4e3a\u4e34\u5e8a\u795e\u7ecf\u5fc3\u7406\u5b66\u4e2d\u4f7f\u7528\u6700\u5e7f\u7684\u6d4b\u9a8c\u4e4b\u4e00\uff0c\u5982\u4eca\u4e5f\u662f\u8111\u529b\u8bad\u7ec3\u5e94\u7528\u4e2d\u7684\u5e38\u5ba2\u3002",creator:"\u5b83\u4e8e 1948 \u5e74\u7531\u5a01\u65af\u5eb7\u661f\u5927\u5b66\u7684 David A. Grant \u548c Esta A. Berg \u53d1\u8868\u5728\u300a\u5b9e\u9a8c\u5fc3\u7406\u5b66\u6742\u5fd7\u300b\uff08Journal of Experimental Psychology\uff09\u4e0a\uff1b\u5176\u8bbe\u8ba1\u8131\u80ce\u4e8e Berg \u65e9\u5148\u7684\u7855\u58eb\u5de5\u4f5c\u3002\u5b83\u53d6\u6750\u4e8e\u66f4\u65e9\u7684\u6b27\u6d32\u6982\u5ff5\u5f62\u6210\u4e0e\u5206\u7c7b\u4efb\u52a1\u4f20\u7edf\uff0c\u800c\u975e\u51ed\u7a7a\u53d1\u660e\u3002",methods:"\u628a\u6bcf\u4e2a\u9519\u8bef\u7b54\u6848\u90fd\u5f53\u4f5c\u4fe1\u606f\uff0c\u800c\u4e0d\u662f\u5931\u8d25\uff1a\u5b83\u544a\u8bc9\u4f60\u5f53\u524d\u89c4\u5219\u4e0d\u662f\u4f60\u6b63\u5728\u7528\u7684\u90a3\u6761\uff0c\u6240\u4ee5\u8981\u6709\u610f\u8bc6\u5730\u5207\u6362\uff0c\u800c\u4e0d\u662f\u778e\u731c\u3002\u5f62\u6210\u4e00\u4e2a\u660e\u786e\u7684\u5047\u8bbe\uff08\u201c\u73b0\u5728\u662f\u989c\u8272\u201d\uff09\uff0c\u53bb\u68c0\u9a8c\u5b83\uff0c\u4e00\u65e6\u53cd\u9988\u4e0e\u4f60\u76f8\u6096\uff0c\u5c31\u8fc5\u901f\u653e\u5f03\u5b83\u2014\u2014\u8ffd\u7740\u4e00\u6761\u5df2\u7ecf\u5931\u6548\u7684\u89c4\u5219\u4e0d\u653e\uff0c\u662f\u4ee3\u4ef7\u6700\u9ad8\u7684\u9519\u8bef\u3002\u5728\u89c4\u5219\u521a\u7ffb\u8f6c\u4e4b\u540e\u4fdd\u6301\u51b7\u9759\uff1b\u90a3\u91cc\u6b63\u662f\u5927\u591a\u6570\u9519\u8bef\u624e\u5806\u7684\u5730\u65b9\u3002",duration:"\u77ed\u800c\u89c4\u5f8b\u80dc\u8fc7\u957f\u800c\u7a00\u758f\uff1a\u6bcf\u6b21 5 \u5230 10 \u5206\u949f\u3001\u6bcf\u5468\u51e0\u6b21\uff0c\u5c31\u8db3\u591f\u4e86\u3002\u4e00\u65e6\u4f60\u5bdf\u89c9\u6ce8\u610f\u529b\u5f00\u59cb\u6e9c\u8d70\u5c31\u505c\u4e0b\u6765\uff0c\u56e0\u4e3a\u75b2\u52b3\u6070\u6070\u4f1a\u4ea7\u751f\u8fd9\u9879\u4efb\u52a1\u672c\u5e94\u51cf\u5c11\u7684\u90a3\u79cd\u50f5\u5316\u3001\u91cd\u590d\u7684\u9519\u8bef\u3002",research:"\u8bc1\u636e\u6700\u5f3a\u7684\uff0c\u662f\u4f60\u80fd\u6599\u5230\u7684\u90a3\u4e00\u9762\u2014\u2014\u4f60\u4f1a\u5728\u8fd9\u9879\u4efb\u52a1\u4ee5\u53ca\u4e0e\u4e4b\u5bc6\u5207\u76f8\u5173\u7684\u5206\u7c7b\u548c\u5207\u6362\u4efb\u52a1\u4e0a\u53d8\u5f97\u66f4\u597d\uff0c\u800c\u4e14\u5b83\u4ecd\u662f\u4e00\u4e2a\u7ecf\u4e34\u5e8a\u9a8c\u8bc1\u7684\u3001\u5bf9\u6267\u884c\u529f\u80fd\u548c\u989d\u53f6\u529f\u80fd\u969c\u788d\u654f\u611f\u7684\u6807\u8bb0\u3002\u4f46\u5b83\u654f\u611f\u5374\u4e0d\u7279\u5f02\uff1a\u8868\u73b0\u4e0d\u4f73\u53ef\u80fd\u6e90\u81ea\u6ce8\u610f\u6216\u8bb0\u5fc6\uff0c\u800c\u975e\u5355\u7eaf\u7684\u7075\u6d3b\u6027\u95ee\u9898\uff0c\u5b83\u7684\u91cd\u6d4b\u4fe1\u5ea6\u4e5f\u53ea\u662f\u4e2d\u7b49\uff0c\u81f3\u4e8e\u66f4\u5927\u7684\u627f\u8bfa\u2014\u2014\u8bad\u7ec3\u5b83\u80fd\u63d0\u5347\u4e00\u822c\u667a\u529b\u3001\u6216\u80fd\u5e7f\u6cdb\u8fc1\u79fb\u5230\u65e5\u5e38\u51b3\u7b56\u2014\u2014\u5219\u5927\u4f53\u4e0a\u672a\u83b7\u8bc1\u5b9e\u3002\u5bf9\u90a3\u4e9b\u5b8f\u5927\u7684\u8bf4\u6cd5\u8981\u4fdd\u6301\u8c28\u614e\u3002",rec:"\u5728\u89c4\u5219\u521a\u6539\u53d8\u4e4b\u540e\u6162\u4e0b\u6765\u4e00\u62cd\u2014\u2014\u8fd9\u552f\u4e00\u7684\u4e00\u6b21\u505c\u987f\uff0c\u5c31\u80fd\u963b\u6b62\u5927\u591a\u6570\u56fa\u7740\u6027\u9519\u8bef\u3002",faq:[["\u4e3a\u4ec0\u4e48\u89c4\u5219\u8001\u662f\u53d8\u8fd8\u4e0d\u544a\u8bc9\u6211\uff1f","\u90a3\u4e2a\u9690\u85cf\u7684\u53d8\u5316\u6b63\u662f\u5168\u90e8\u610f\u4e49\u6240\u5728\u3002\u8fd9\u9879\u4efb\u52a1\u6d4b\u7684\u662f\u4f60\u591a\u5feb\u80fd\u5bdf\u89c9\u65e7\u89c4\u5219\u5df2\u7ecf\u5931\u6548\u5e76\u5207\u6362\u5230\u65b0\u89c4\u5219\uff0c\u6240\u4ee5\u4e00\u6761\u9884\u5148\u5ba3\u5e03\u7684\u89c4\u5219\uff0c\u6070\u6070\u4f1a\u62b9\u6389\u6b63\u5728\u88ab\u8bad\u7ec3\u7684\u90a3\u9879\u6280\u80fd\u3002"],["\u5c31\u7b97\u9519\u4e86\u6211\u8fd8\u662f\u4e00\u76f4\u6309\u540c\u4e00\u4e2a\u7279\u5f81\u5206\u7c7b\u2014\u2014\u8fd9\u6837\u4e0d\u597d\u5417\uff1f","\u5728\u4e00\u6761\u89c4\u5219\u5931\u6548\u540e\u8fd8\u91cd\u590d\u7528\u5b83\uff0c\u8fd9\u53eb\u56fa\u7740\u6027\u9519\u8bef\uff0c\u800c\u5b83\u6b63\u662f\u8fd9\u91cc\u6700\u6709\u4fe1\u606f\u91cf\u7684\u4e00\u4e2a\u4fe1\u53f7\u3002\u5bdf\u89c9\u5e76\u6253\u7834\u90a3\u4e2a\u5faa\u73af\u672c\u8eab\u5c31\u662f\u8fd9\u9879\u6280\u80fd\uff0c\u6240\u4ee5\u80fd\u902e\u4f4f\u81ea\u5df1\u5728\u8fd9\u4e48\u505a\uff0c\u5c31\u662f\u5b9e\u5b9e\u5728\u5728\u7684\u8fdb\u6b65\u3002"],["\u8fd9\u4f1a\u8ba9\u6211\u6574\u4f53\u4e0a\u66f4\u806a\u660e\u6216\u66f4\u4f1a\u505a\u51b3\u5b9a\u5417\uff1f","\u8bf4\u5b9e\u8bdd\uff0c\u5927\u6982\u4e0d\u4f1a\u6709\u4ec0\u4e48\u5bbd\u6cdb\u7684\u6548\u679c\u3002\u4f60\u4f1a\u53ef\u9760\u5730\u5728\u5206\u7c7b\u548c\u89c4\u5219\u5207\u6362\u4efb\u52a1\u4e0a\u53d8\u5f97\u66f4\u597d\uff0c\u4f46\u8bf4\u5b83\u80fd\u63d0\u5347\u4e00\u822c\u667a\u529b\u6216\u8fc1\u79fb\u5230\u65e5\u5e38\u9009\u62e9\u4e0a\u7684\u624e\u5b9e\u8bc1\u636e\u662f\u7f3a\u4e4f\u7684\uff0c\u6240\u4ee5\u7ec3\u5b83\u662f\u56e0\u4e3a\u8fd9\u9879\u6280\u80fd\u672c\u8eab\u6709\u7528\uff0c\u800c\u4e0d\u662f\u4e3a\u4e86\u63d0\u5347\u667a\u5546\u3002"]],variants:"\u4e0d\u540c\u7248\u672c\u7684\u5dee\u522b\u5728\u4e8e\u5361\u7247\u7684\u6570\u91cf\u3001\u89c4\u5219\u662f\u6309\u56fa\u5b9a\u8ba1\u5212\u8fd8\u662f\u4e0d\u53ef\u9884\u6d4b\u5730\u8f6c\u6362\uff0c\u4ee5\u53ca\u4f60\u80fd\u5f97\u5230\u591a\u5c11\u53cd\u9988\u3002\u4fee\u8ba2\u8fc7\u7684\u7b80\u77ed\u7248\u672c\uff08\u6bd4\u5982 48 \u5f20\u5361\u7684 Nelson \u7248\uff09\u53bb\u6389\u4e86\u6a21\u7cca\u7684\u5361\u7247\uff0c\u8ba1\u7b97\u673a\u5316\u7248\u672c\u52a0\u5165\u4e86\u8ba1\u65f6\u548c\u53cd\u5e94\u901f\u5ea6\u7684\u6d4b\u91cf\uff0c\u800c\u50cf\u7ef4\u5ea6\u53d8\u5316\u5361\u7247\u5206\u7c7b\uff08Dimensional Change Card Sort\uff09\u8fd9\u6837\u9002\u5408\u513f\u7ae5\u7684\u53d8\u4f53\uff0c\u5219\u4e3a\u66f4\u5c0f\u7684\u73a9\u5bb6\u7b80\u5316\u4e86\u89c4\u5219\u3002"}},"word-pairs":{ru:{about:"\u041f\u0430\u0440\u044b \u0441\u043b\u043e\u0432 - \u044d\u0442\u043e \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u0435 \u043d\u0430 \u0430\u0441\u0441\u043e\u0446\u0438\u0430\u0442\u0438\u0432\u043d\u0443\u044e \u043f\u0430\u043c\u044f\u0442\u044c \u043f\u043e \u043c\u0435\u0442\u043e\u0434\u0443 \u043f\u0430\u0440\u043d\u044b\u0445 \u0430\u0441\u0441\u043e\u0446\u0438\u0430\u0446\u0438\u0439. \u0412\u0430\u043c \u043f\u043e\u043a\u0430\u0437\u044b\u0432\u0430\u044e\u0442 \u0441\u043f\u0438\u0441\u043e\u043a \u043f\u0430\u0440 \u0441\u043b\u043e\u0432 (\u043d\u0430\u043f\u0440\u0438\u043c\u0435\u0440, \u044f\u0431\u043b\u043e\u043a\u043e - \u043c\u043e\u0441\u0442), \u0434\u0430\u0451\u0442\u0441\u044f \u0432\u0440\u0435\u043c\u044f \u0438\u0445 \u0437\u0430\u043f\u043e\u043c\u043d\u0438\u0442\u044c, \u0430 \u0437\u0430\u0442\u0435\u043c \u0432\u044b\u0432\u043e\u0434\u0438\u0442\u0441\u044f \u043e\u0434\u043d\u043e \u0441\u043b\u043e\u0432\u043e \u0438\u0437 \u043f\u0430\u0440\u044b - \u043d\u0443\u0436\u043d\u043e \u0432\u0441\u043f\u043e\u043c\u043d\u0438\u0442\u044c \u0432\u0442\u043e\u0440\u043e\u0435.",benefit:"\u0422\u0440\u0435\u043d\u0438\u0440\u0443\u0435\u0442 \u0430\u0441\u0441\u043e\u0446\u0438\u0430\u0442\u0438\u0432\u043d\u0443\u044e \u043f\u0430\u043c\u044f\u0442\u044c \u0438 \u0443\u043c\u0435\u043d\u0438\u0435 \u043e\u0441\u043e\u0437\u043d\u0430\u043d\u043d\u043e \u0441\u0432\u044f\u0437\u044b\u0432\u0430\u0442\u044c \u043c\u0435\u0436\u0434\u0443 \u0441\u043e\u0431\u043e\u0439 \u043f\u0440\u043e\u0438\u0437\u0432\u043e\u043b\u044c\u043d\u044b\u0435 \u044d\u043b\u0435\u043c\u0435\u043d\u0442\u044b - \u0442\u043e\u0442 \u0436\u0435 \u043d\u0430\u0432\u044b\u043a, \u0447\u0442\u043e \u0441\u0442\u043e\u0438\u0442 \u0437\u0430 \u0437\u0430\u043f\u043e\u043c\u0438\u043d\u0430\u043d\u0438\u0435\u043c \u0438\u043c\u0451\u043d \u043f\u043e \u043b\u0438\u0446\u0430\u043c, \u0438\u043d\u043e\u0441\u0442\u0440\u0430\u043d\u043d\u044b\u0445 \u0441\u043b\u043e\u0432 \u0438 \u0442\u043e\u0433\u043e, \u043a\u0443\u0434\u0430 \u0432\u044b \u0447\u0442\u043e-\u0442\u043e \u043f\u043e\u043b\u043e\u0436\u0438\u043b\u0438.",history:"\u041c\u0435\u0442\u043e\u0434 \u043f\u0430\u0440\u043d\u044b\u0445 \u0430\u0441\u0441\u043e\u0446\u0438\u0430\u0446\u0438\u0439 \u0432\u044b\u0440\u043e\u0441 \u0438\u0437 \u043f\u0435\u0440\u0432\u043e\u0439 \u0432\u043e\u043b\u043d\u044b \u044d\u043a\u0441\u043f\u0435\u0440\u0438\u043c\u0435\u043d\u0442\u0430\u043b\u044c\u043d\u044b\u0445 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u0439 \u043f\u0430\u043c\u044f\u0442\u0438 \u043a\u043e\u043d\u0446\u0430 XIX \u0432\u0435\u043a\u0430 - \u0442\u043e\u0439 \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u0438, \u043a\u043e\u0442\u043e\u0440\u0443\u044e \u0432 1885 \u0433\u043e\u0434\u0443 \u043e\u0442\u043a\u0440\u044b\u043b \u0413\u0435\u0440\u043c\u0430\u043d \u042d\u0431\u0431\u0438\u043d\u0433\u0430\u0443\u0437 \u0441\u0432\u043e\u0438\u043c\u0438 \u043e\u043f\u044b\u0442\u0430\u043c\u0438 \u0441 \u0431\u0435\u0441\u0441\u043c\u044b\u0441\u043b\u0435\u043d\u043d\u044b\u043c\u0438 \u0441\u043b\u043e\u0433\u0430\u043c\u0438. \u041e\u043d \u0441\u0442\u0430\u043b \u043e\u0434\u043d\u0438\u043c \u0438\u0437 \u0441\u0442\u0430\u043d\u0434\u0430\u0440\u0442\u043d\u044b\u0445 \u043b\u0430\u0431\u043e\u0440\u0430\u0442\u043e\u0440\u043d\u044b\u0445 \u0438\u043d\u0441\u0442\u0440\u0443\u043c\u0435\u043d\u0442\u043e\u0432 \u0438\u0437\u0443\u0447\u0435\u043d\u0438\u044f \u0442\u043e\u0433\u043e, \u043a\u0430\u043a \u043e\u0431\u0440\u0430\u0437\u0443\u044e\u0442\u0441\u044f \u0430\u0441\u0441\u043e\u0446\u0438\u0430\u0446\u0438\u0438, \u0430 \u043e\u0442\u0442\u0443\u0434\u0430 \u043f\u0435\u0440\u0435\u0448\u0451\u043b \u0432 \u043e\u0431\u0443\u0447\u0435\u043d\u0438\u0435 \u043b\u0435\u043a\u0441\u0438\u043a\u0435, \u0432 \u0440\u0430\u0431\u043e\u0442\u0443 \u0441 \u043f\u0430\u043c\u044f\u0442\u044c\u044e \u0432 \u043a\u043b\u0438\u043d\u0438\u043a\u0430\u0445 \u0438 \u0432 \u043f\u0440\u0438\u043b\u043e\u0436\u0435\u043d\u0438\u044f \u0434\u043b\u044f \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0438 \u043c\u043e\u0437\u0433\u0430.",creator:"\u041c\u0435\u0442\u043e\u0434 \u043e\u0431\u044b\u0447\u043d\u043e \u0441\u0432\u044f\u0437\u044b\u0432\u0430\u044e\u0442 \u0441 \u0430\u043c\u0435\u0440\u0438\u043a\u0430\u043d\u0441\u043a\u0438\u043c \u043f\u0441\u0438\u0445\u043e\u043b\u043e\u0433\u043e\u043c \u041c\u044d\u0440\u0438 \u0423\u0438\u0442\u043e\u043d \u041a\u0430\u043b\u043a\u0438\u043d\u0441, \u043e\u043f\u0438\u0441\u0430\u0432\u0448\u0435\u0439 \u0435\u0433\u043e \u0432 \u0440\u0430\u0431\u043e\u0442\u0430\u0445 1894 - 1896 \u0433\u043e\u0434\u043e\u0432 \u043e\u0431 \u0430\u0441\u0441\u043e\u0446\u0438\u0430\u0446\u0438\u044f\u0445, \u0433\u0434\u0435 \u043e\u043d\u0430 \u0438\u0437\u0443\u0447\u0430\u043b\u0430 \u0432\u043b\u0438\u044f\u043d\u0438\u0435 \u0447\u0430\u0441\u0442\u043e\u0442\u044b, \u043d\u043e\u0432\u0438\u0437\u043d\u044b, \u043f\u0435\u0440\u0432\u0438\u0447\u043d\u043e\u0441\u0442\u0438 \u0438 \u044f\u0440\u043a\u043e\u0441\u0442\u0438. \u0415\u0451 \u0438\u043d\u0442\u0435\u0440\u0435\u0441\u043e\u0432\u0430\u043b\u0430 \u043d\u0435 \u0438\u0433\u0440\u0430-\u0442\u0440\u0435\u043d\u0430\u0436\u0451\u0440, \u0430 \u0441\u043f\u043e\u0441\u043e\u0431 \u0438\u0437\u043c\u0435\u0440\u0438\u0442\u044c, \u043a\u0430\u043a \u043e\u0431\u0440\u0430\u0437\u0443\u044e\u0442\u0441\u044f \u0441\u0432\u044f\u0437\u0438 \u043c\u0435\u0436\u0434\u0443 \u044d\u043b\u0435\u043c\u0435\u043d\u0442\u0430\u043c\u0438; \u0438\u0441\u0442\u043e\u0440\u0438\u043a\u0438 \u0443\u0442\u043e\u0447\u043d\u044f\u044e\u0442, \u0447\u0442\u043e \u0442\u043e\u0447\u043d\u0435\u0435 \u043d\u0430\u0437\u044b\u0432\u0430\u0442\u044c \u0435\u0451 \u043d\u0435 \u0435\u0434\u0438\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0439 \u0438\u0437\u043e\u0431\u0440\u0435\u0442\u0430\u0442\u0435\u043b\u044c\u043d\u0438\u0446\u0435\u0439, \u0430 \u0442\u0435\u043c, \u043a\u0442\u043e \u0432\u0432\u0451\u043b \u043c\u0435\u0442\u043e\u0434 \u0432 \u0448\u0438\u0440\u043e\u043a\u0438\u0439 \u043d\u0430\u0443\u0447\u043d\u044b\u0439 \u043e\u0431\u0438\u0445\u043e\u0434.",methods:"\u041d\u0435 \u043f\u044b\u0442\u0430\u0439\u0442\u0435\u0441\u044c \u0437\u0443\u0431\u0440\u0438\u0442\u044c \u043f\u0430\u0440\u044b \u043c\u0435\u0445\u0430\u043d\u0438\u0447\u0435\u0441\u043a\u0438\u043c \u043f\u043e\u0432\u0442\u043e\u0440\u043e\u043c. \u0421\u0442\u0440\u043e\u0439\u0442\u0435 \u044f\u0440\u043a\u0438\u0439 \u043c\u044b\u0441\u043b\u0435\u043d\u043d\u044b\u0439 \u043e\u0431\u0440\u0430\u0437 \u0438\u043b\u0438 \u043a\u043e\u0440\u043e\u0442\u043a\u0443\u044e \u0438\u0441\u0442\u043e\u0440\u0438\u044e, \u0441\u0432\u044f\u0437\u044b\u0432\u0430\u044e\u0449\u0443\u044e \u043e\u0431\u0430 \u0441\u043b\u043e\u0432\u0430 (\u043f\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u044c\u0442\u0435 \u044f\u0431\u043b\u043e\u043a\u043e, \u0431\u0430\u043b\u0430\u043d\u0441\u0438\u0440\u0443\u044e\u0449\u0435\u0435 \u043d\u0430 \u043c\u043e\u0441\u0442\u0443) - \u0447\u0435\u043c \u043d\u0435\u043b\u0435\u043f\u0435\u0435 \u043a\u0430\u0440\u0442\u0438\u043d\u043a\u0430, \u0442\u0435\u043c \u043a\u0440\u0435\u043f\u0447\u0435 \u0434\u0435\u0440\u0436\u0438\u0442\u0441\u044f. \u041f\u0440\u043e\u0432\u0435\u0440\u044f\u0439\u0442\u0435 \u0441\u0435\u0431\u044f \u0438\u043c\u0435\u043d\u043d\u043e \u043f\u0440\u0438\u043f\u043e\u043c\u0438\u043d\u0430\u043d\u0438\u0435\u043c, \u0430 \u043d\u0435 \u043f\u0435\u0440\u0435\u0447\u0438\u0442\u044b\u0432\u0430\u043d\u0438\u0435\u043c, \u0438 \u0440\u0430\u0437\u043d\u043e\u0441\u0438\u0442\u0435 \u043f\u043e\u0432\u0442\u043e\u0440\u044b \u0432\u043e \u0432\u0440\u0435\u043c\u0435\u043d\u0438.",duration:"\u041a\u043e\u0440\u043e\u0442\u043a\u0438\u0435 \u0447\u0430\u0441\u0442\u044b\u0435 \u043f\u043e\u0434\u0445\u043e\u0434\u044b \u043b\u0443\u0447\u0448\u0435 \u0434\u043b\u0438\u043d\u043d\u044b\u0445: 5 - 10 \u043c\u0438\u043d\u0443\u0442 \u0432 \u0434\u0435\u043d\u044c \u0431\u043e\u043b\u0435\u0435 \u0447\u0435\u043c \u0434\u043e\u0441\u0442\u0430\u0442\u043e\u0447\u043d\u043e, \u0438 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442 \u0434\u0430\u0451\u0442 \u0441\u0430\u043c\u0430 \u043f\u0440\u043e\u0432\u0435\u0440\u043a\u0430 \u0441\u0435\u0431\u044f, \u0430 \u043d\u0435 \u0440\u0430\u0437\u0433\u043b\u044f\u0434\u044b\u0432\u0430\u043d\u0438\u0435 \u0441\u043f\u0438\u0441\u043a\u0430.",research:"\u0414\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u043d\u0435\u0435 \u0432\u0441\u0435\u0433\u043e \u0440\u043e\u0432\u043d\u043e \u0442\u043e, \u0447\u0435\u0433\u043e \u0438 \u0441\u0442\u043e\u0438\u0442 \u0436\u0434\u0430\u0442\u044c: \u0432\u044b \u043b\u0443\u0447\u0448\u0435 \u0437\u0430\u043f\u043e\u043c\u0438\u043d\u0430\u0435\u0442\u0435 \u0438\u043c\u0435\u043d\u043d\u043e \u043f\u0430\u0440\u043d\u044b\u0435 \u0430\u0441\u0441\u043e\u0446\u0438\u0430\u0446\u0438\u0438, \u0430 \u043f\u0440\u0438\u0451\u043c\u044b \u0441 \u043e\u0431\u0440\u0430\u0437\u0430\u043c\u0438 \u0438 \u0438\u0441\u0442\u043e\u0440\u0438\u044f\u043c\u0438 \u043d\u0430\u0434\u0451\u0436\u043d\u043e \u043f\u043e\u043c\u043e\u0433\u0430\u044e\u0442 \u0443\u0441\u0432\u0430\u0438\u0432\u0430\u0442\u044c \u0442\u0430\u043a\u043e\u0439 \u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b. \u0423\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043d\u0438\u044f, \u0447\u0442\u043e \u044d\u0442\u043e \u0432 \u0446\u0435\u043b\u043e\u043c \u043e\u0431\u043e\u0441\u0442\u0440\u044f\u0435\u0442 \u043f\u0430\u043c\u044f\u0442\u044c, \u043f\u043e\u0434\u043d\u0438\u043c\u0430\u0435\u0442 IQ \u0438\u043b\u0438 \u043e\u0442\u043e\u0434\u0432\u0438\u0433\u0430\u0435\u0442 \u0432\u043e\u0437\u0440\u0430\u0441\u0442\u043d\u043e\u0439 \u0441\u043f\u0430\u0434, \u043a\u0443\u0434\u0430 \u0441\u043b\u0430\u0431\u0435\u0435: \u043a\u0440\u0443\u043f\u043d\u044b\u0435 \u043e\u0431\u0437\u043e\u0440\u044b \u0442\u0440\u0435\u043d\u0430\u0436\u0451\u0440\u043e\u0432 \u0434\u043b\u044f \u043c\u043e\u0437\u0433\u0430 \u043f\u043e\u043a\u0430\u0437\u044b\u0432\u0430\u044e\u0442, \u0447\u0442\u043e \u0442\u0430\u043a\u043e\u0439 \u0448\u0438\u0440\u043e\u043a\u0438\u0439 \u043f\u0435\u0440\u0435\u043d\u043e\u0441 \u043f\u043e\u0447\u0442\u0438 \u043d\u0435 \u0432\u043e\u0437\u043d\u0438\u043a\u0430\u0435\u0442, \u043f\u043e\u044d\u0442\u043e\u043c\u0443 \u043a \u0433\u0440\u043e\u043c\u043a\u0438\u043c \u043e\u0431\u0435\u0449\u0430\u043d\u0438\u044f\u043c \u043e\u0442\u043d\u043e\u0441\u0438\u0442\u0435\u0441\u044c \u043e\u0441\u0442\u043e\u0440\u043e\u0436\u043d\u043e, \u0430 \u0446\u0435\u043d\u043d\u043e\u0441\u0442\u044c \u0443\u043f\u0440\u0430\u0436\u043d\u0435\u043d\u0438\u044f \u0432\u0438\u0434\u044c\u0442\u0435 \u0432 \u043a\u043e\u043d\u043a\u0440\u0435\u0442\u043d\u043e\u043c \u043d\u0430\u0432\u044b\u043a\u0435 \u043a\u043e\u0434\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u044f \u0441\u0432\u044f\u0437\u0435\u0439.",rec:"\u0412\u0441\u0435\u0433\u0434\u0430 \u0441\u0432\u044f\u0437\u044b\u0432\u0430\u0439\u0442\u0435 \u043a\u0430\u0436\u0434\u0443\u044e \u043f\u0430\u0440\u0443 \u044f\u0440\u043a\u0438\u043c \u043c\u044b\u0441\u043b\u0435\u043d\u043d\u044b\u043c \u043e\u0431\u0440\u0430\u0437\u043e\u043c \u0432\u043c\u0435\u0441\u0442\u043e \u043f\u043e\u0432\u0442\u043e\u0440\u0435\u043d\u0438\u044f \u0441\u043b\u043e\u0432 - \u044d\u0442\u043e \u0435\u0434\u0438\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0435 \u0438\u0437\u043c\u0435\u043d\u0435\u043d\u0438\u0435, \u043a\u043e\u0442\u043e\u0440\u043e\u0435 \u0441\u0438\u043b\u044c\u043d\u0435\u0435 \u0432\u0441\u0435\u0433\u043e \u0443\u043b\u0443\u0447\u0448\u0430\u0435\u0442 \u043f\u0440\u0438\u043f\u043e\u043c\u0438\u043d\u0430\u043d\u0438\u0435.",faq:[["\u0423\u043b\u0443\u0447\u0448\u0438\u0442 \u043b\u0438 \u0442\u0440\u0435\u043d\u0438\u0440\u043e\u0432\u043a\u0430 \u043d\u0430 \u043f\u0430\u0440\u0430\u0445 \u0441\u043b\u043e\u0432 \u043c\u043e\u044e \u043f\u0430\u043c\u044f\u0442\u044c \u0432 \u043e\u0431\u044b\u0447\u043d\u043e\u0439 \u0436\u0438\u0437\u043d\u0438?","\u041e\u043d\u0430 \u043d\u0430\u0434\u0451\u0436\u043d\u043e \u0443\u043b\u0443\u0447\u0448\u0430\u0435\u0442 \u0437\u0430\u043f\u043e\u043c\u0438\u043d\u0430\u043d\u0438\u0435 \u043f\u0430\u0440\u043d\u043e\u0433\u043e \u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u0430 \u0438 \u0443\u043c\u0435\u043d\u0438\u0435 \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u0442\u044c \u043e\u0431\u0440\u0430\u0437\u044b - \u044d\u0442\u043e \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u0438\u0442\u0441\u044f \u043d\u0430 \u0438\u043c\u0435\u043d\u0430 \u0438 \u043b\u0435\u043a\u0441\u0438\u043a\u0443. \u041e\u0431\u0449\u0435\u0433\u043e \u0443\u043b\u0443\u0447\u0448\u0435\u043d\u0438\u044f \u043f\u0430\u043c\u044f\u0442\u0438 \u043d\u0430 \u0432\u0441\u0451 \u043f\u043e\u0434\u0440\u044f\u0434 \u0434\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u044c\u0441\u0442\u0432\u0430 \u043d\u0435 \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u044e\u0442, \u0442\u0430\u043a \u0447\u0442\u043e \u0441\u0447\u0438\u0442\u0430\u0439\u0442\u0435 \u044d\u0442\u043e \u043f\u043e\u043b\u0435\u0437\u043d\u044b\u043c \u043f\u0440\u0438\u0451\u043c\u043e\u043c, \u0430 \u043d\u0435 \u043f\u0430\u043d\u0430\u0446\u0435\u0435\u0439."],["\u041a\u0430\u043a \u043b\u0443\u0447\u0448\u0435 \u0432\u0441\u0435\u0433\u043e \u0437\u0430\u043f\u043e\u043c\u043d\u0438\u0442\u044c \u0442\u0440\u0443\u0434\u043d\u0443\u044e \u043f\u0430\u0440\u0443?","\u041f\u0440\u0435\u0432\u0440\u0430\u0442\u0438\u0442\u0435 \u0434\u0432\u0430 \u0441\u043b\u043e\u0432\u0430 \u0432 \u043e\u0434\u0438\u043d \u044f\u0440\u043a\u0438\u0439, \u0447\u0443\u0442\u044c \u0430\u0431\u0441\u0443\u0440\u0434\u043d\u044b\u0439 \u043c\u044b\u0441\u043b\u0435\u043d\u043d\u044b\u0439 \u043e\u0431\u0440\u0430\u0437 \u0438\u043b\u0438 \u043c\u0438\u043d\u0438-\u0441\u0446\u0435\u043d\u043a\u0443, \u0433\u0434\u0435 \u0435\u0441\u0442\u044c \u043e\u0431\u0430. \u041a\u043e\u043d\u043a\u0440\u0435\u0442\u043d\u044b\u0435 \u043d\u0435\u043e\u0436\u0438\u0434\u0430\u043d\u043d\u044b\u0435 \u043a\u0430\u0440\u0442\u0438\u043d\u043a\u0438 \u0432\u0441\u043f\u043e\u043c\u0438\u043d\u0430\u044e\u0442\u0441\u044f \u043a\u0443\u0434\u0430 \u043b\u0443\u0447\u0448\u0435, \u0447\u0435\u043c \u0431\u0435\u0437\u0437\u0432\u0443\u0447\u043d\u044b\u0439 \u043f\u043e\u0432\u0442\u043e\u0440."],["\u0421 \u043a\u0430\u043a\u043e\u0433\u043e \u0447\u0438\u0441\u043b\u0430 \u043f\u0430\u0440 \u043d\u0430\u0447\u0438\u043d\u0430\u0442\u044c?","\u041d\u0430\u0447\u043d\u0438\u0442\u0435 \u0441 \u043a\u043e\u0440\u043e\u0442\u043a\u043e\u0433\u043e \u0441\u043f\u0438\u0441\u043a\u0430, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u0443\u0434\u0430\u0451\u0442\u0441\u044f \u043f\u0440\u043e\u0439\u0442\u0438 \u0431\u0435\u0437 \u043e\u0448\u0438\u0431\u043e\u043a, - \u043f\u0440\u0438\u043c\u0435\u0440\u043d\u043e \u043f\u044f\u0442\u044c-\u0432\u043e\u0441\u0435\u043c\u044c \u043f\u0430\u0440, \u0437\u0430\u0442\u0435\u043c \u043d\u0430\u0440\u0430\u0449\u0438\u0432\u0430\u0439\u0442\u0435. \u0423\u0441\u043f\u0435\u0445 \u043d\u0430 \u043c\u0430\u043b\u043e\u043c \u043d\u0430\u0431\u043e\u0440\u0435 \u0437\u0430\u043a\u0440\u0435\u043f\u043b\u044f\u0435\u0442 \u043d\u0430\u0432\u044b\u043a \u043a\u043e\u0434\u0438\u0440\u043e\u0432\u0430\u043d\u0438\u044f \u043b\u0443\u0447\u0448\u0435, \u0447\u0435\u043c \u043f\u0440\u043e\u0432\u0430\u043b \u043d\u0430 \u0434\u043b\u0438\u043d\u043d\u043e\u043c."]],variants:"\u0412\u0430\u0440\u0438\u0430\u043d\u0442\u044b \u0437\u0430\u043c\u0435\u043d\u044f\u044e\u0442 \u043f\u0430\u0440\u044b \u0441\u043b\u043e\u0432 \u043d\u0430 \u0441\u043b\u043e\u0432\u043e-\u043a\u0430\u0440\u0442\u0438\u043d\u043a\u0443, \u043b\u0438\u0446\u043e-\u0438\u043c\u044f \u0438\u043b\u0438 \u0438\u043d\u043e\u0441\u0442\u0440\u0430\u043d\u043d\u043e\u0435 \u0441\u043b\u043e\u0432\u043e-\u043f\u0435\u0440\u0435\u0432\u043e\u0434, \u0443\u0434\u043b\u0438\u043d\u044f\u044e\u0442 \u0441\u043f\u0438\u0441\u043e\u043a, \u0434\u043e\u0431\u0430\u0432\u043b\u044f\u044e\u0442 \u043f\u0430\u0443\u0437\u0443 \u043f\u0435\u0440\u0435\u0434 \u043f\u0440\u0438\u043f\u043e\u043c\u0438\u043d\u0430\u043d\u0438\u0435\u043c \u043b\u0438\u0431\u043e \u043f\u0440\u043e\u0441\u044f\u0442 \u0432\u043e\u0441\u043f\u0440\u043e\u0438\u0437\u0432\u0435\u0441\u0442\u0438 \u043e\u0431\u0430 \u044d\u043b\u0435\u043c\u0435\u043d\u0442\u0430 \u043f\u0430\u0440\u044b, \u0430 \u043d\u0435 \u043e\u0434\u043d\u0443 \u043f\u043e\u0434\u0441\u043a\u0430\u0437\u043a\u0443 \u0438 \u043e\u0434\u0438\u043d \u043e\u0442\u0432\u0435\u0442."},en:{about:"Word Pairs is a paired-associate memory exercise. You are shown a list of two-word pairs (for example, apple - bridge) to study for a short time, then one word of each pair is presented and your job is to recall its partner.",benefit:"It trains associative memory and the deliberate encoding of arbitrary links between items, which is the same skill behind remembering names with faces, foreign vocabulary, and where you put things.",history:"The paired-associate method grew out of the first wave of experimental memory research at the end of the 19th century, in the tradition Hermann Ebbinghaus opened with his nonsense-syllable studies in 1885. It became one of the standard laboratory tools for studying how associations are formed, and from there spread into vocabulary teaching, memory clinics, and brain-training apps.",creator:"The technique is commonly credited to the American psychologist Mary Whiton Calkins, who described it in her 1894 - 1896 work on association while studying the effects of frequency, recency, primacy and vividness. She was not chasing a 'training game' but a way to measure how links between items form, and historians note she is best described as the method's populariser rather than its sole inventor.",methods:"Do not try to memorise pairs by brute repetition. Build a vivid mental image or a tiny story that links the two words (picture the apple balanced on the bridge), and the stranger the image, the better it sticks. Test yourself by recalling rather than re-reading, and space your reviews out over time.",duration:"Short, frequent sessions beat long ones: 5 to 10 minutes a day is plenty, and the act of testing yourself is where the gain comes from, not the studying.",research:"Evidence is strongest for exactly what you would expect - you get better at memorising paired associations, and the imagery and story tricks you practise reliably help you learn this kind of material. Claims that it broadly sharpens memory, raises IQ or holds off age-related decline are much weaker: large reviews of brain training find that such 'far transfer' mostly fails to appear, so treat the grand promises with caution and value the exercise for the concrete encoding habit it builds.",rec:"Always link each pair with a vivid mental picture instead of repeating the words - it is the single change that most improves recall.",faq:[["Does training on word pairs make my everyday memory better?","It reliably makes you better at learning paired material and at using imagery to memorise, which transfers to things like names and vocabulary. A broad upgrade to all-round memory is not supported by the evidence, so think of it as a useful technique rather than a cure."],["What is the best way to remember a difficult pair?","Turn the two words into one vivid, slightly absurd mental image or mini-scene that contains both. Concrete, surprising images are recalled far better than silent repetition."],["How many pairs should I start with?","Begin with a short list you can get fully right, around five to eight pairs, then grow it. Succeeding on a small set teaches the encoding habit better than failing on a long one."]],variants:"Variations swap word pairs for word-and-image, face-and-name, or foreign-word-and-translation, lengthen the list, add a delay before recall, or ask you to reproduce both members of the pair rather than one cue and one answer."},es:{about:"Pares de Palabras es un ejercicio de memoria de asociaci\xf3n de pares. Se te muestra una lista de pares de dos palabras (por ejemplo, manzana - puente) para estudiarla durante un breve tiempo y, despu\xe9s, se te presenta una palabra de cada par y tu tarea es recordar su compa\xf1era.",benefit:"Entrena la memoria asociativa y la codificaci\xf3n deliberada de v\xednculos arbitrarios entre elementos, que es la misma destreza que hay detr\xe1s de recordar nombres junto a caras, vocabulario de un idioma extranjero y d\xf3nde dejaste las cosas.",history:"El m\xe9todo de asociaci\xf3n de pares surgi\xf3 de la primera oleada de investigaci\xf3n experimental sobre la memoria a finales del siglo XIX, en la tradici\xf3n que Hermann Ebbinghaus abri\xf3 con sus estudios de s\xedlabas sin sentido en 1885. Se convirti\xf3 en una de las herramientas est\xe1ndar de laboratorio para estudiar c\xf3mo se forman las asociaciones, y de ah\xed pas\xf3 a la ense\xf1anza de vocabulario, a las cl\xednicas de memoria y a las aplicaciones de entrenamiento cerebral.",creator:"La t\xe9cnica suele atribuirse a la psic\xf3loga estadounidense Mary Whiton Calkins, que la describi\xf3 en su trabajo de 1894 - 1896 sobre la asociaci\xf3n al estudiar los efectos de la frecuencia, la proximidad, la primac\xeda y la viveza. No buscaba un 'juego de entrenamiento', sino una forma de medir c\xf3mo se forman los v\xednculos entre elementos, y los historiadores se\xf1alan que se la describe mejor como la divulgadora del m\xe9todo que como su \xfanica inventora.",methods:"No intentes memorizar los pares por pura repetici\xf3n. Construye una imagen mental v\xedvida o una peque\xf1a historia que enlace las dos palabras (imagina la manzana en equilibrio sobre el puente); cuanto m\xe1s extra\xf1a sea la imagen, mejor se fija. Ponte a prueba recordando en lugar de releer, y espacia tus repasos en el tiempo.",duration:"Las sesiones cortas y frecuentes ganan a las largas: de 5 a 10 minutos al d\xeda bastan, y el provecho viene del acto de ponerte a prueba, no del estudio.",research:"La evidencia es m\xe1s s\xf3lida justo en lo que cabr\xeda esperar: mejoras en memorizar asociaciones de pares, y los trucos de im\xe1genes e historias que practicas ayudan de forma fiable a aprender este tipo de material. Las afirmaciones de que agudiza la memoria en general, eleva el CI o frena el deterioro asociado a la edad son mucho m\xe1s d\xe9biles: las grandes revisiones del entrenamiento cerebral concluyen que esa 'transferencia lejana' casi nunca aparece, as\xed que toma con cautela las grandes promesas y valora el ejercicio por el h\xe1bito concreto de codificaci\xf3n que construye.",rec:"Enlaza siempre cada par con una imagen mental v\xedvida en vez de repetir las palabras: es el \xfanico cambio que m\xe1s mejora el recuerdo.",faq:[["\xbfEntrenar con pares de palabras mejora mi memoria cotidiana?","De forma fiable te hace mejor aprendiendo material por pares y usando im\xe1genes para memorizar, lo que se traslada a cosas como nombres y vocabulario. Una mejora amplia de toda la memoria no est\xe1 respaldada por la evidencia, as\xed que piensa en ello como una t\xe9cnica \xfatil m\xe1s que como una cura."],["\xbfCu\xe1l es la mejor manera de recordar un par dif\xedcil?","Convierte las dos palabras en una imagen mental o una mini escena v\xedvida y algo absurda que contenga ambas. Las im\xe1genes concretas y sorprendentes se recuerdan mucho mejor que la repetici\xf3n en silencio."],["\xbfCon cu\xe1ntos pares deber\xeda empezar?","Empieza con una lista corta que puedas acertar por completo, de unos cinco a ocho pares, y luego hazla crecer. Acertar en un conjunto peque\xf1o ense\xf1a mejor el h\xe1bito de codificaci\xf3n que fallar en uno largo."]],variants:"Las variantes cambian los pares de palabras por palabra-e-imagen, cara-y-nombre o palabra-extranjera-y-traducci\xf3n, alargan la lista, a\xf1aden un retardo antes del recuerdo, o te piden reproducir ambos miembros del par en lugar de una pista y una respuesta."},de:{about:"Word Pairs ist eine Ged\xe4chtnis\xfcbung zum Lernen von Paarassoziationen. Dir wird eine Liste von Wortpaaren gezeigt (zum Beispiel Apfel \u2013 Br\xfccke), die du kurz einpr\xe4gen sollst; danach wird je ein Wort jedes Paares gezeigt, und du musst seinen Partner abrufen.",benefit:"Es trainiert das assoziative Ged\xe4chtnis und das bewusste Einpr\xe4gen willk\xfcrlicher Verbindungen zwischen Dingen \u2013 dieselbe F\xe4higkeit, die hinter dem Merken von Namen zu Gesichtern, fremdsprachigem Vokabular und dem Ort steckt, an dem man etwas abgelegt hat.",history:"Die Methode der Paarassoziation entstand aus der ersten Welle der experimentellen Ged\xe4chtnisforschung am Ende des 19. Jahrhunderts, in der Tradition, die Hermann Ebbinghaus 1885 mit seinen Studien zu sinnlosen Silben begr\xfcndete. Sie wurde zu einem der g\xe4ngigen Laborwerkzeuge, um zu untersuchen, wie Assoziationen entstehen, und gelangte von dort in den Vokabelunterricht, in Ged\xe4chtniskliniken und in Gehirntraining-Apps.",creator:"Die Technik wird gew\xf6hnlich der amerikanischen Psychologin Mary Whiton Calkins zugeschrieben, die sie in ihren Arbeiten zur Assoziation von 1894\u20131896 beschrieb, w\xe4hrend sie die Wirkung von H\xe4ufigkeit, Aktualit\xe4t, Primat und Lebendigkeit untersuchte. Sie verfolgte kein \u201eTrainingsspiel\u201c, sondern eine Methode, um zu messen, wie Verbindungen zwischen Dingen entstehen; Historiker beschreiben sie am treffendsten als Wegbereiterin der Methode, nicht als ihre alleinige Erfinderin.",methods:"Versuche nicht, Paare durch stumpfe Wiederholung zu lernen. Baue ein lebhaftes inneres Bild oder eine winzige Geschichte, die die beiden W\xf6rter verbindet (stell dir den Apfel vor, der auf der Br\xfccke balanciert) \u2013 und je merkw\xfcrdiger das Bild, desto besser bleibt es haften. Pr\xfcfe dich, indem du abrufst statt erneut liest, und verteile deine Wiederholungen \xfcber die Zeit.",duration:"Kurze, h\xe4ufige Sitzungen schlagen lange: 5 bis 10 Minuten am Tag reichen v\xf6llig, und der Gewinn kommt aus dem Akt des Selbstabfragens, nicht aus dem Lernen.",research:"Am besten belegt ist genau das, was man erwarten w\xfcrde: Du wirst besser darin, Paarassoziationen zu lernen, und die Bild- und Geschichtentricks, die du \xfcbst, helfen verl\xe4sslich beim Lernen solcher Inhalte. Behauptungen, es sch\xe4rfe das Ged\xe4chtnis allgemein, hebe den IQ oder halte den altersbedingten Abbau auf, sind weit schw\xe4cher: Gro\xdfe \xdcbersichtsarbeiten zum Gehirntraining finden, dass ein solcher \u201eFerntransfer\u201c meist ausbleibt \u2013 die gro\xdfen Versprechen also mit Vorsicht genie\xdfen und die \xdcbung wegen der konkreten Einpr\xe4ge-Gewohnheit sch\xe4tzen, die sie aufbaut.",rec:"Verkn\xfcpfe jedes Paar stets mit einem lebhaften inneren Bild, statt die W\xf6rter zu wiederholen \u2013 das ist die einzelne \xc4nderung, die den Abruf am st\xe4rksten verbessert.",faq:[["Macht das Training mit Wortpaaren mein allt\xe4gliches Ged\xe4chtnis besser?","Es macht dich verl\xe4sslich besser darin, Paarmaterial zu lernen und Bilder zum Einpr\xe4gen zu nutzen, was sich auf Dinge wie Namen und Vokabeln \xfcbertr\xe4gt. Eine breite Verbesserung des Ged\xe4chtnisses insgesamt ist durch die Belege nicht gedeckt \u2013 betrachte es also als n\xfctzliche Technik, nicht als Wundermittel."],["Wie merkt man sich ein schwieriges Paar am besten?","Verwandle die beiden W\xf6rter in ein lebhaftes, leicht absurdes inneres Bild oder eine Mini-Szene, die beide enth\xe4lt. Konkrete, \xfcberraschende Bilder werden weit besser abgerufen als stumme Wiederholung."],["Mit wie vielen Paaren sollte ich anfangen?","Beginne mit einer kurzen Liste, die du vollst\xe4ndig richtig schaffst, etwa f\xfcnf bis acht Paaren, und vergr\xf6\xdfere sie dann. Auf einer kleinen Menge zu bestehen lehrt die Einpr\xe4ge-Gewohnheit besser, als an einer langen zu scheitern."]],variants:"Variationen tauschen Wortpaare gegen Wort-und-Bild, Gesicht-und-Name oder Fremdwort-und-\xdcbersetzung, verl\xe4ngern die Liste, f\xfcgen vor dem Abruf eine Verz\xf6gerung ein oder verlangen, dass du beide Glieder des Paares wiedergibst statt nur einen Hinweis und eine Antwort."},pt:{about:"Word Pairs \xe9 um exerc\xedcio de mem\xf3ria de associa\xe7\xe3o de pares. S\xe3o mostrados a voc\xea uma lista de pares de duas palavras (por exemplo, ma\xe7\xe3 - ponte) para estudar por um tempo curto; depois uma palavra de cada par \xe9 apresentada e seu trabalho \xe9 lembrar a sua parceira.",benefit:"Treina a mem\xf3ria associativa e a codifica\xe7\xe3o deliberada de liga\xe7\xf5es arbitr\xe1rias entre itens, que \xe9 a mesma habilidade por tr\xe1s de lembrar nomes junto com rostos, vocabul\xe1rio de idiomas e onde voc\xea guardou as coisas.",history:"O m\xe9todo de associa\xe7\xe3o de pares surgiu da primeira onda da pesquisa experimental sobre mem\xf3ria, no fim do s\xe9culo XIX, na tradi\xe7\xe3o que Hermann Ebbinghaus abriu com seus estudos de s\xedlabas sem sentido em 1885. Tornou-se uma das ferramentas padr\xe3o de laborat\xf3rio para estudar como as associa\xe7\xf5es se formam e, a partir da\xed, espalhou-se para o ensino de vocabul\xe1rio, as cl\xednicas de mem\xf3ria e os aplicativos de treino cerebral.",creator:"A t\xe9cnica costuma ser creditada \xe0 psic\xf3loga norte-americana Mary Whiton Calkins, que a descreveu em seu trabalho de 1894 - 1896 sobre associa\xe7\xe3o, ao estudar os efeitos de frequ\xeancia, rec\xeancia, primazia e vivacidade. Ela n\xe3o estava atr\xe1s de um \"jogo de treino\", mas de uma forma de medir como as liga\xe7\xf5es entre itens se formam, e os historiadores observam que \xe9 mais bem descrita como a divulgadora do m\xe9todo do que como sua \xfanica inventora.",methods:"N\xe3o tente memorizar os pares pela repeti\xe7\xe3o bruta. Construa uma imagem mental v\xedvida ou uma pequena hist\xf3ria que ligue as duas palavras (imagine a ma\xe7\xe3 equilibrada sobre a ponte), e quanto mais estranha a imagem, melhor ela gruda. Teste-se recordando, em vez de reler, e espalhe suas revis\xf5es ao longo do tempo.",duration:"Sess\xf5es curtas e frequentes vencem as longas: 5 a 10 minutos por dia j\xe1 bastam, e o ganho vem do ato de se testar, n\xe3o do estudo.",research:"A evid\xeancia \xe9 mais forte exatamente para o que se esperaria: voc\xea fica melhor em memorizar associa\xe7\xf5es de pares, e os truques de imagem e de hist\xf3ria que voc\xea pratica ajudam de forma confi\xe1vel a aprender esse tipo de material. As alega\xe7\xf5es de que isso agu\xe7a a mem\xf3ria de modo amplo, eleva o QI ou retarda o decl\xednio ligado \xe0 idade s\xe3o bem mais fracas: grandes revis\xf5es sobre treino cerebral concluem que essa \"transfer\xeancia ampla\" quase nunca aparece, ent\xe3o encare as grandes promessas com cautela e valorize o exerc\xedcio pelo h\xe1bito concreto de codifica\xe7\xe3o que ele constr\xf3i.",rec:"Ligue sempre cada par a uma imagem mental v\xedvida em vez de repetir as palavras \u2014 \xe9 a \xfanica mudan\xe7a que mais melhora a recorda\xe7\xe3o.",faq:[["Treinar com pares de palavras deixa minha mem\xf3ria do dia a dia melhor?","Ele melhora de forma confi\xe1vel a sua capacidade de aprender material em pares e de usar imagens para memorizar, o que se transfere para coisas como nomes e vocabul\xe1rio. Uma melhora ampla da mem\xf3ria em geral n\xe3o tem respaldo nas evid\xeancias, ent\xe3o pense nele como uma t\xe9cnica \xfatil, e n\xe3o como uma cura."],["Qual \xe9 a melhor forma de lembrar um par dif\xedcil?","Transforme as duas palavras em uma imagem mental v\xedvida e um pouco absurda, ou numa minicena que contenha as duas. Imagens concretas e surpreendentes s\xe3o lembradas muito melhor do que a repeti\xe7\xe3o silenciosa."],["Com quantos pares devo come\xe7ar?","Comece com uma lista curta que voc\xea consiga acertar por inteiro, uns cinco a oito pares, e depois aumente. Acertar um conjunto pequeno ensina melhor o h\xe1bito de codifica\xe7\xe3o do que errar um longo."]],variants:"As varia\xe7\xf5es trocam pares de palavras por palavra-e-imagem, rosto-e-nome ou palavra-estrangeira-e-tradu\xe7\xe3o, alongam a lista, acrescentam um atraso antes da recorda\xe7\xe3o, ou pedem que voc\xea reproduza os dois membros do par, em vez de uma pista e uma resposta."},hi:{about:"\u0935\u0930\u094d\u0921 \u092a\u0947\u092f\u0930\u094d\u0938 \u090f\u0915 \u092f\u0941\u0917\u094d\u092e-\u0938\u093e\u0939\u091a\u0930\u094d\u092f (paired-associate) \u0938\u094d\u092e\u0943\u0924\u093f \u0905\u092d\u094d\u092f\u093e\u0938 \u0939\u0948\u0964 \u0906\u092a\u0915\u094b \u0926\u094b-\u0936\u092c\u094d\u0926\u094b\u0902 \u0935\u093e\u0932\u0947 \u091c\u094b\u0921\u093c\u094b\u0902 \u0915\u0940 \u090f\u0915 \u0938\u0942\u091a\u0940 (\u0909\u0926\u093e\u0939\u0930\u0923 \u0915\u0947 \u0932\u093f\u090f, \u0938\u0947\u092c - \u092a\u0941\u0932) \u0925\u094b\u0921\u093c\u0940 \u0926\u0947\u0930 \u092a\u0922\u093c\u0928\u0947 \u0915\u0947 \u0932\u093f\u090f \u0926\u093f\u0916\u093e\u0908 \u091c\u093e\u0924\u0940 \u0939\u0948, \u092b\u093f\u0930 \u0939\u0930 \u091c\u094b\u0921\u093c\u0947 \u0915\u093e \u090f\u0915 \u0936\u092c\u094d\u0926 \u0938\u093e\u092e\u0928\u0947 \u0930\u0916\u093e \u091c\u093e\u0924\u093e \u0939\u0948 \u0914\u0930 \u0906\u092a\u0915\u093e \u0915\u093e\u092e \u0939\u0948 \u0909\u0938\u0915\u0947 \u0938\u093e\u0925\u0940 \u0915\u094b \u092f\u093e\u0926 \u0915\u0930\u0928\u093e\u0964",benefit:"\u092f\u0939 \u0938\u093e\u0939\u091a\u0930\u094d\u092f \u0938\u094d\u092e\u0943\u0924\u093f \u0914\u0930 \u091a\u0940\u091c\u093c\u094b\u0902 \u0915\u0947 \u092c\u0940\u091a \u0928\u093f\u0930\u0930\u094d\u0925\u0915 \u091c\u0941\u0921\u093c\u093e\u0935\u094b\u0902 \u0915\u094b \u0938\u094b\u091a-\u0938\u092e\u091d\u0915\u0930 \u090f\u0928\u094d\u0915\u094b\u0921 \u0915\u0930\u0928\u0947 \u0915\u094b \u0938\u093e\u0927\u0924\u093e \u0939\u0948, \u091c\u094b \u0935\u0939\u0940 \u0939\u0941\u0928\u0930 \u0939\u0948 \u091c\u093f\u0938\u0915\u0947 \u092a\u0940\u091b\u0947 \u091a\u0947\u0939\u0930\u094b\u0902 \u0915\u0947 \u0938\u093e\u0925 \u0928\u093e\u092e \u092f\u093e\u0926 \u0930\u0916\u0928\u093e, \u0935\u093f\u0926\u0947\u0936\u0940 \u0936\u092c\u094d\u0926\u093e\u0935\u0932\u0940, \u0914\u0930 \u091a\u0940\u091c\u093c\u0947\u0902 \u0915\u0939\u093e\u0901 \u0930\u0916\u0940\u0902 \u092f\u0939 \u092f\u093e\u0926 \u0930\u0916\u0928\u093e \u091b\u093f\u092a\u093e \u0939\u0948\u0964",history:"\u092f\u0941\u0917\u094d\u092e-\u0938\u093e\u0939\u091a\u0930\u094d\u092f \u0935\u093f\u0927\u093f 19\u0935\u0940\u0902 \u0938\u0926\u0940 \u0915\u0947 \u0905\u0902\u0924 \u092e\u0947\u0902 \u092a\u094d\u0930\u093e\u092f\u094b\u0917\u093f\u0915 \u0938\u094d\u092e\u0943\u0924\u093f-\u0905\u0928\u0941\u0938\u0902\u0927\u093e\u0928 \u0915\u0940 \u092a\u0939\u0932\u0940 \u0932\u0939\u0930 \u0938\u0947 \u0928\u093f\u0915\u0932\u0940, \u0909\u0938\u0940 \u092a\u0930\u0902\u092a\u0930\u093e \u092e\u0947\u0902 \u091c\u093f\u0938\u0947 \u0939\u0930\u092e\u0928 \u090f\u092c\u093f\u0902\u0917\u0939\u093e\u0909\u0938 (Hermann Ebbinghaus) \u0928\u0947 1885 \u092e\u0947\u0902 \u0905\u092a\u0928\u0947 \u0928\u093f\u0930\u0930\u094d\u0925\u0915-\u0905\u0915\u094d\u0937\u0930 \u0905\u0927\u094d\u092f\u092f\u0928\u094b\u0902 \u0938\u0947 \u0916\u094b\u0932\u093e\u0964 \u092f\u0939 \u091c\u0941\u0921\u093c\u093e\u0935 \u0915\u0948\u0938\u0947 \u092c\u0928\u0924\u0947 \u0939\u0948\u0902 \u0907\u0938\u0915\u093e \u0905\u0927\u094d\u092f\u092f\u0928 \u0915\u0930\u0928\u0947 \u0915\u0947 \u092e\u093e\u0928\u0915 \u092a\u094d\u0930\u092f\u094b\u0917\u0936\u093e\u0932\u093e \u0914\u091c\u093c\u093e\u0930\u094b\u0902 \u092e\u0947\u0902 \u0938\u0947 \u090f\u0915 \u092c\u0928 \u0917\u0908, \u0914\u0930 \u0935\u0939\u093e\u0901 \u0938\u0947 \u0936\u092c\u094d\u0926\u093e\u0935\u0932\u0940-\u0936\u093f\u0915\u094d\u0937\u0923, \u0938\u094d\u092e\u0943\u0924\u093f-\u0915\u094d\u0932\u0940\u0928\u093f\u0915\u094b\u0902 \u0914\u0930 \u092c\u094d\u0930\u0947\u0928-\u091f\u094d\u0930\u0947\u0928\u093f\u0902\u0917 \u0910\u092a\u094d\u0938 \u092e\u0947\u0902 \u092b\u0948\u0932 \u0917\u0908\u0964",creator:"\u0907\u0938 \u0924\u0915\u0928\u0940\u0915 \u0915\u093e \u0936\u094d\u0930\u0947\u092f \u0906\u092e\u0924\u094c\u0930 \u092a\u0930 \u0905\u092e\u0947\u0930\u093f\u0915\u0940 \u092e\u0928\u094b\u0935\u0948\u091c\u094d\u091e\u093e\u0928\u093f\u0915 \u092e\u0948\u0930\u0940 \u0935\u094d\u0939\u093f\u091f\u0928 \u0915\u0949\u0932\u094d\u0915\u093f\u0928\u094d\u0938 (Mary Whiton Calkins) \u0915\u094b \u0926\u093f\u092f\u093e \u091c\u093e\u0924\u093e \u0939\u0948, \u091c\u093f\u0928\u094d\u0939\u094b\u0902\u0928\u0947 \u0907\u0938\u0947 \u0938\u093e\u0939\u091a\u0930\u094d\u092f \u092a\u0930 \u0905\u092a\u0928\u0947 1894 - 1896 \u0915\u0947 \u0915\u093e\u092e \u092e\u0947\u0902 \u0935\u0930\u094d\u0923\u093f\u0924 \u0915\u093f\u092f\u093e, \u091c\u092c \u0935\u0947 \u0906\u0935\u0943\u0924\u094d\u0924\u093f, \u0928\u0935\u0940\u0928\u0924\u093e, \u092a\u094d\u0930\u093e\u0925\u092e\u093f\u0915\u0924\u093e \u0914\u0930 \u091c\u0940\u0935\u0902\u0924\u0924\u093e \u0915\u0947 \u0905\u0938\u0930 \u0915\u093e \u0905\u0927\u094d\u092f\u092f\u0928 \u0915\u0930 \u0930\u0939\u0940 \u0925\u0940\u0902\u0964 \u0935\u0947 \u0915\u093f\u0938\u0940 \"\u091f\u094d\u0930\u0947\u0928\u093f\u0902\u0917 \u0917\u0947\u092e\" \u0915\u0947 \u092a\u0940\u091b\u0947 \u0928\u0939\u0940\u0902 \u0925\u0940\u0902 \u092c\u0932\u094d\u0915\u093f \u092f\u0939 \u092e\u093e\u092a\u0928\u0947 \u0915\u093e \u0924\u0930\u0940\u0915\u093e \u0916\u094b\u091c \u0930\u0939\u0940 \u0925\u0940\u0902 \u0915\u093f \u091a\u0940\u091c\u093c\u094b\u0902 \u0915\u0947 \u092c\u0940\u091a \u091c\u0941\u0921\u093c\u093e\u0935 \u0915\u0948\u0938\u0947 \u092c\u0928\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u0907\u0924\u093f\u0939\u093e\u0938\u0915\u093e\u0930 \u0909\u0928\u094d\u0939\u0947\u0902 \u0907\u0938 \u0935\u093f\u0927\u093f \u0915\u0940 \u090f\u0915\u092e\u093e\u0924\u094d\u0930 \u0906\u0935\u093f\u0937\u094d\u0915\u093e\u0930\u0915 \u0915\u0947 \u092c\u091c\u093e\u092f \u0907\u0938\u0915\u0940 \u0932\u094b\u0915\u092a\u094d\u0930\u093f\u092f \u092c\u0928\u093e\u0928\u0947 \u0935\u093e\u0932\u0940 \u0915\u0939\u0928\u093e \u092c\u0947\u0939\u0924\u0930 \u092e\u093e\u0928\u0924\u0947 \u0939\u0948\u0902\u0964",methods:"\u091c\u094b\u0921\u093c\u094b\u0902 \u0915\u094b \u0915\u094b\u0930\u0940 \u0930\u091f\u093e\u0908 \u0938\u0947 \u092f\u093e\u0926 \u0915\u0930\u0928\u0947 \u0915\u0940 \u0915\u094b\u0936\u093f\u0936 \u0928 \u0915\u0930\u0947\u0902\u0964 \u0926\u094b\u0928\u094b\u0902 \u0936\u092c\u094d\u0926\u094b\u0902 \u0915\u094b \u091c\u094b\u0921\u093c\u0924\u093e \u0939\u0941\u0906 \u090f\u0915 \u091c\u0940\u0935\u0902\u0924 \u092e\u093e\u0928\u0938\u093f\u0915 \u091a\u093f\u0924\u094d\u0930 \u092f\u093e \u090f\u0915 \u0928\u0928\u094d\u0939\u0940 \u0915\u0939\u093e\u0928\u0940 \u092c\u0941\u0928\u0947\u0902 (\u0915\u0932\u094d\u092a\u0928\u093e \u0915\u0930\u0947\u0902 \u0915\u093f \u0938\u0947\u092c \u092a\u0941\u0932 \u092a\u0930 \u0938\u0902\u0924\u0941\u0932\u093f\u0924 \u0939\u0948), \u0914\u0930 \u091a\u093f\u0924\u094d\u0930 \u091c\u093f\u0924\u0928\u093e \u0905\u091c\u0940\u092c \u0939\u094b\u0917\u093e, \u0909\u0924\u0928\u093e \u0939\u0940 \u091f\u093f\u0915\u0947\u0917\u093e\u0964 \u0926\u094b\u092c\u093e\u0930\u093e \u092a\u0922\u093c\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u092f\u093e\u0926 \u0915\u0930\u0915\u0947 \u0916\u093c\u0941\u0926 \u0915\u094b \u092a\u0930\u0916\u0947\u0902, \u0914\u0930 \u0905\u092a\u0928\u0940 \u0938\u092e\u0940\u0915\u094d\u0937\u093e\u0913\u0902 \u0915\u094b \u0938\u092e\u092f \u0915\u0947 \u0938\u093e\u0925 \u092b\u0948\u0932\u093e\u090f\u0901\u0964",duration:"\u091b\u094b\u091f\u0947, \u092c\u093e\u0930-\u092c\u093e\u0930 \u0935\u093e\u0932\u0947 \u0938\u0924\u094d\u0930 \u0932\u0902\u092c\u0947 \u0938\u0924\u094d\u0930\u094b\u0902 \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u0939\u0948\u0902: \u0930\u094b\u091c\u093c 5 \u0938\u0947 10 \u092e\u093f\u0928\u091f \u0915\u093e\u092b\u093c\u0940 \u0939\u0948\u0902, \u0914\u0930 \u0932\u093e\u092d \u0916\u093c\u0941\u0926 \u0915\u094b \u092a\u0930\u0916\u0928\u0947 \u0915\u0947 \u0915\u093e\u092e \u0938\u0947 \u0906\u0924\u093e \u0939\u0948, \u092a\u0922\u093c\u093e\u0908 \u0938\u0947 \u0928\u0939\u0940\u0902\u0964",research:"\u091c\u093f\u0938\u0915\u0940 \u0905\u092a\u0947\u0915\u094d\u0937\u093e \u0939\u0948, \u092a\u094d\u0930\u092e\u093e\u0923 \u0920\u0940\u0915 \u0909\u0938\u0940 \u0915\u0947 \u0932\u093f\u090f \u0938\u092c\u0938\u0947 \u092e\u091c\u093c\u092c\u0942\u0924 \u0939\u0948\u0902 - \u0906\u092a \u092f\u0941\u0917\u094d\u092e-\u0938\u093e\u0939\u091a\u0930\u094d\u092f\u094b\u0902 \u0915\u094b \u092f\u093e\u0926 \u0915\u0930\u0928\u0947 \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u0939\u094b \u091c\u093e\u0924\u0947 \u0939\u0948\u0902, \u0914\u0930 \u091c\u094b \u091a\u093f\u0924\u094d\u0930- \u0914\u0930 \u0915\u0939\u093e\u0928\u0940-\u0924\u0930\u0915\u0940\u092c\u0947\u0902 \u0906\u092a \u0938\u093e\u0927\u0924\u0947 \u0939\u0948\u0902 \u0935\u0947 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0930\u0942\u092a \u0938\u0947 \u0907\u0938 \u0924\u0930\u0939 \u0915\u0940 \u0938\u093e\u092e\u0917\u094d\u0930\u0940 \u0938\u0940\u0916\u0928\u0947 \u092e\u0947\u0902 \u092e\u0926\u0926 \u0915\u0930\u0924\u0940 \u0939\u0948\u0902\u0964 \u092f\u0939 \u0926\u093e\u0935\u0947 \u0915\u093f \u0907\u0938\u0938\u0947 \u0938\u094d\u092e\u0943\u0924\u093f \u0935\u094d\u092f\u093e\u092a\u0915 \u0930\u0942\u092a \u0938\u0947 \u0924\u0947\u091c\u093c \u0939\u094b\u0924\u0940 \u0939\u0948, IQ \u092c\u0922\u093c\u0924\u093e \u0939\u0948 \u092f\u093e \u0909\u092e\u094d\u0930-\u0938\u0902\u092c\u0902\u0927\u0940 \u0917\u093f\u0930\u093e\u0935\u091f \u091f\u0932\u0924\u0940 \u0939\u0948, \u0915\u0939\u0940\u0902 \u0915\u092e\u091c\u093c\u094b\u0930 \u0939\u0948\u0902: \u092c\u094d\u0930\u0947\u0928-\u091f\u094d\u0930\u0947\u0928\u093f\u0902\u0917 \u0915\u0940 \u092c\u0921\u093c\u0940 \u0938\u092e\u0940\u0915\u094d\u0937\u093e\u090f\u0901 \u092a\u093e\u0924\u0940 \u0939\u0948\u0902 \u0915\u093f \u0910\u0938\u093e \"\u0926\u0942\u0930-\u0939\u0938\u094d\u0924\u093e\u0902\u0924\u0930\u0923\" \u091c\u093c\u094d\u092f\u093e\u0926\u093e\u0924\u0930 \u0926\u093f\u0916\u0924\u093e \u0939\u0940 \u0928\u0939\u0940\u0902 \u2014 \u0907\u0938\u0932\u093f\u090f \u092c\u0921\u093c\u0947 \u0935\u093e\u0926\u094b\u0902 \u0915\u094b \u0938\u093e\u0935\u0927\u093e\u0928\u0940 \u0938\u0947 \u0932\u0947\u0902 \u0914\u0930 \u0907\u0938 \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u094b \u0909\u0938 \u0920\u094b\u0938 \u090f\u0928\u094d\u0915\u094b\u0921\u093f\u0902\u0917-\u0906\u0926\u0924 \u0915\u0947 \u0932\u093f\u090f \u0938\u0930\u093e\u0939\u0947\u0902 \u091c\u094b \u092f\u0939 \u092c\u0928\u093e\u0924\u093e \u0939\u0948\u0964",rec:"\u0939\u0930 \u091c\u094b\u0921\u093c\u0947 \u0915\u094b \u0936\u092c\u094d\u0926\u094b\u0902 \u0915\u094b \u0926\u094b\u0939\u0930\u093e\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u0939\u092e\u0947\u0936\u093e \u090f\u0915 \u091c\u0940\u0935\u0902\u0924 \u092e\u093e\u0928\u0938\u093f\u0915 \u091a\u093f\u0924\u094d\u0930 \u0938\u0947 \u091c\u094b\u0921\u093c\u0947\u0902 - \u092f\u0939\u0940 \u090f\u0915\u092e\u093e\u0924\u094d\u0930 \u092c\u0926\u0932\u093e\u0935 \u0939\u0948 \u091c\u094b \u0938\u094d\u092e\u0930\u0923 \u0915\u094b \u0938\u092c\u0938\u0947 \u091c\u093c\u094d\u092f\u093e\u0926\u093e \u0938\u0941\u0927\u093e\u0930\u0924\u093e \u0939\u0948\u0964",faq:[["\u0915\u094d\u092f\u093e \u0936\u092c\u094d\u0926-\u091c\u094b\u0921\u093c\u094b\u0902 \u092a\u0930 \u0905\u092d\u094d\u092f\u093e\u0938 \u0915\u0930\u0928\u0947 \u0938\u0947 \u092e\u0947\u0930\u0940 \u0930\u094b\u091c\u093c\u092e\u0930\u094d\u0930\u093e \u0915\u0940 \u0938\u094d\u092e\u0943\u0924\u093f \u092c\u0947\u0939\u0924\u0930 \u0939\u094b\u0924\u0940 \u0939\u0948?","\u092f\u0939 \u092d\u0930\u094b\u0938\u0947\u092e\u0902\u0926 \u0930\u0942\u092a \u0938\u0947 \u0906\u092a\u0915\u094b \u092f\u0941\u0917\u094d\u092e-\u0938\u093e\u092e\u0917\u094d\u0930\u0940 \u0938\u0940\u0916\u0928\u0947 \u0914\u0930 \u091a\u093f\u0924\u094d\u0930\u094b\u0902 \u0938\u0947 \u092f\u093e\u0926 \u0915\u0930\u0928\u0947 \u092e\u0947\u0902 \u092c\u0947\u0939\u0924\u0930 \u092c\u0928\u093e\u0924\u093e \u0939\u0948, \u091c\u094b \u0928\u093e\u092e\u094b\u0902 \u0914\u0930 \u0936\u092c\u094d\u0926\u093e\u0935\u0932\u0940 \u091c\u0948\u0938\u0940 \u091a\u0940\u091c\u093c\u094b\u0902 \u0924\u0915 \u0939\u0938\u094d\u0924\u093e\u0902\u0924\u0930\u093f\u0924 \u0939\u094b\u0924\u093e \u0939\u0948\u0964 \u0939\u0930 \u0924\u0930\u092b\u093c \u0915\u0940 \u0938\u094d\u092e\u0943\u0924\u093f \u092e\u0947\u0902 \u0935\u094d\u092f\u093e\u092a\u0915 \u0938\u0941\u0927\u093e\u0930 \u092a\u094d\u0930\u092e\u093e\u0923\u094b\u0902 \u0938\u0947 \u0938\u092e\u0930\u094d\u0925\u093f\u0924 \u0928\u0939\u0940\u0902 \u0939\u0948, \u0907\u0938\u0932\u093f\u090f \u0907\u0938\u0947 \u0915\u094b\u0908 \u0907\u0932\u093e\u091c \u092e\u093e\u0928\u0928\u0947 \u0915\u0947 \u092c\u091c\u093e\u092f \u090f\u0915 \u0909\u092a\u092f\u094b\u0917\u0940 \u0924\u0915\u0928\u0940\u0915 \u0938\u092e\u091d\u0947\u0902\u0964"],["\u0915\u093f\u0938\u0940 \u0915\u0920\u093f\u0928 \u091c\u094b\u0921\u093c\u0947 \u0915\u094b \u092f\u093e\u0926 \u0930\u0916\u0928\u0947 \u0915\u093e \u0938\u092c\u0938\u0947 \u0905\u091a\u094d\u091b\u093e \u0924\u0930\u0940\u0915\u093e \u0915\u094d\u092f\u093e \u0939\u0948?","\u0926\u094b\u0928\u094b\u0902 \u0936\u092c\u094d\u0926\u094b\u0902 \u0915\u094b \u090f\u0915 \u091c\u0940\u0935\u0902\u0924, \u0925\u094b\u0921\u093c\u0947 \u092c\u0947\u0924\u0941\u0915\u0947 \u092e\u093e\u0928\u0938\u093f\u0915 \u091a\u093f\u0924\u094d\u0930 \u092f\u093e \u0928\u0928\u094d\u0939\u0947 \u0926\u0943\u0936\u094d\u092f \u092e\u0947\u0902 \u092c\u0926\u0932 \u0926\u0947\u0902 \u091c\u093f\u0938\u092e\u0947\u0902 \u0926\u094b\u0928\u094b\u0902 \u0938\u092e\u093e\u090f \u0939\u094b\u0902\u0964 \u0920\u094b\u0938, \u091a\u094c\u0902\u0915\u093e\u0928\u0947 \u0935\u093e\u0932\u0947 \u091a\u093f\u0924\u094d\u0930 \u091a\u0941\u092a\u091a\u093e\u092a \u0926\u094b\u0939\u0930\u093e\u0928\u0947 \u0938\u0947 \u0915\u0939\u0940\u0902 \u092c\u0947\u0939\u0924\u0930 \u092f\u093e\u0926 \u0930\u0939\u0924\u0947 \u0939\u0948\u0902\u0964"],["\u092e\u0941\u091d\u0947 \u0915\u093f\u0924\u0928\u0947 \u091c\u094b\u0921\u093c\u094b\u0902 \u0938\u0947 \u0936\u0941\u0930\u0942 \u0915\u0930\u0928\u093e \u091a\u093e\u0939\u093f\u090f?","\u090f\u0915 \u091b\u094b\u091f\u0940 \u0938\u0942\u091a\u0940 \u0938\u0947 \u0936\u0941\u0930\u0942 \u0915\u0930\u0947\u0902 \u091c\u093f\u0938\u0947 \u0906\u092a \u092a\u0942\u0930\u0940 \u0924\u0930\u0939 \u0938\u0939\u0940 \u0915\u0930 \u0938\u0915\u0947\u0902, \u0915\u0930\u0940\u092c \u092a\u093e\u0901\u091a \u0938\u0947 \u0906\u0920 \u091c\u094b\u0921\u093c\u0947, \u092b\u093f\u0930 \u0909\u0938\u0947 \u092c\u0922\u093c\u093e\u090f\u0901\u0964 \u090f\u0915 \u091b\u094b\u091f\u0947 \u0938\u0947\u091f \u092a\u0930 \u0938\u092b\u0932 \u0939\u094b\u0928\u093e, \u090f\u0915 \u0932\u0902\u092c\u0940 \u0938\u0942\u091a\u0940 \u092a\u0930 \u0905\u0938\u092b\u0932 \u0939\u094b\u0928\u0947 \u0938\u0947 \u092c\u0947\u0939\u0924\u0930 \u090f\u0928\u094d\u0915\u094b\u0921\u093f\u0902\u0917-\u0906\u0926\u0924 \u0938\u093f\u0916\u093e\u0924\u093e \u0939\u0948\u0964"]],variants:"\u0935\u093f\u0935\u093f\u0927\u0924\u093e\u090f\u0901 \u0936\u092c\u094d\u0926-\u091c\u094b\u0921\u093c\u094b\u0902 \u0915\u0940 \u091c\u0917\u0939 \u0936\u092c\u094d\u0926-\u0914\u0930-\u091a\u093f\u0924\u094d\u0930, \u091a\u0947\u0939\u0930\u093e-\u0914\u0930-\u0928\u093e\u092e, \u092f\u093e \u0935\u093f\u0926\u0947\u0936\u0940-\u0936\u092c\u094d\u0926-\u0914\u0930-\u0905\u0928\u0941\u0935\u093e\u0926 \u0930\u0916 \u0926\u0947\u0924\u0940 \u0939\u0948\u0902, \u0938\u0942\u091a\u0940 \u0915\u094b \u0932\u0902\u092c\u093e \u0915\u0930 \u0926\u0947\u0924\u0940 \u0939\u0948\u0902, \u0938\u094d\u092e\u0930\u0923 \u0938\u0947 \u092a\u0939\u0932\u0947 \u090f\u0915 \u0926\u0947\u0930\u0940 \u091c\u094b\u0921\u093c \u0926\u0947\u0924\u0940 \u0939\u0948\u0902, \u092f\u093e \u090f\u0915 \u0938\u0902\u0915\u0947\u0924 \u0914\u0930 \u090f\u0915 \u0909\u0924\u094d\u0924\u0930 \u0915\u0947 \u092c\u091c\u093e\u092f \u091c\u094b\u0921\u093c\u0947 \u0915\u0947 \u0926\u094b\u0928\u094b\u0902 \u0938\u0926\u0938\u094d\u092f\u094b\u0902 \u0915\u094b \u0926\u094b\u092c\u093e\u0930\u093e \u092c\u0924\u093e\u0928\u0947 \u0915\u094b \u0915\u0939\u0924\u0940 \u0939\u0948\u0902\u0964"},zh:{about:"\u300a\u8bcd\u8bed\u914d\u5bf9\u300b\u662f\u4e00\u9879\u8054\u60f3\u914d\u5bf9\u8bb0\u5fc6\u7ec3\u4e60\u3002\u5c4f\u5e55\u5148\u7ed9\u4f60\u4e00\u4efd\u7531\u4e24\u4e2a\u8bcd\u7ec4\u6210\u7684\u8bcd\u5bf9\u6e05\u5355\uff08\u4f8b\u5982\uff0c\u82f9\u679c - \u6865\uff09\u4f9b\u4f60\u77ed\u6682\u8bb0\u5fc6\uff0c\u968f\u540e\u5448\u73b0\u6bcf\u4e00\u5bf9\u4e2d\u7684\u4e00\u4e2a\u8bcd\uff0c\u4f60\u7684\u4efb\u52a1\u662f\u56de\u5fc6\u51fa\u5b83\u7684\u642d\u6863\u3002",benefit:"\u5b83\u8bad\u7ec3\u8054\u60f3\u8bb0\u5fc6\uff0c\u4ee5\u53ca\u5728\u6761\u76ee\u4e4b\u95f4\u523b\u610f\u7f16\u7801\u4efb\u610f\u8054\u7cfb\u7684\u80fd\u529b\u2014\u2014\u8fd9\u6b63\u662f\u201c\u8bb0\u4f4f\u4eba\u8138\u914d\u540d\u5b57\u3001\u5916\u8bed\u8bcd\u6c47\u3001\u4e1c\u897f\u653e\u54ea\u4e86\u201d\u80cc\u540e\u6240\u7528\u7684\u540c\u4e00\u79cd\u672c\u9886\u3002",history:"\u8054\u60f3\u914d\u5bf9\u65b9\u6cd5\u8131\u80ce\u4e8e 19 \u4e16\u7eaa\u672b\u7b2c\u4e00\u6ce2\u5b9e\u9a8c\u8bb0\u5fc6\u7814\u7a76\uff0c\u627f\u88ad\u8d6b\u5c14\u66fc\xb7\u827e\u5bbe\u6d69\u65af\uff08Hermann Ebbinghaus\uff09\u4e8e 1885 \u5e74\u4ee5\u65e0\u610f\u4e49\u97f3\u8282\u7814\u7a76\u5f00\u521b\u7684\u4f20\u7edf\u3002\u5b83\u6210\u4e3a\u7814\u7a76\u8054\u7cfb\u5982\u4f55\u5f62\u6210\u7684\u6807\u51c6\u5b9e\u9a8c\u5ba4\u5de5\u5177\u4e4b\u4e00\uff0c\u5e76\u7531\u6b64\u63a8\u5e7f\u5230\u8bcd\u6c47\u6559\u5b66\u3001\u8bb0\u5fc6\u95e8\u8bca\u548c\u8111\u529b\u8bad\u7ec3\u5e94\u7528\u4e2d\u3002",creator:"\u8fd9\u4e00\u6280\u672f\u901a\u5e38\u5f52\u529f\u4e8e\u7f8e\u56fd\u5fc3\u7406\u5b66\u5bb6\u739b\u4e3d\xb7\u60e0\u987f\xb7\u5361\u5c14\u91d1\u65af\uff08Mary Whiton Calkins\uff09\uff0c\u5979\u5728 1894 \u81f3 1896 \u5e74\u7814\u7a76\u8054\u60f3\u7684\u5de5\u4f5c\u4e2d\u63cf\u8ff0\u4e86\u5b83\uff0c\u501f\u6b64\u8003\u5bdf\u9891\u7387\u3001\u8fd1\u56e0\u3001\u9996\u56e0\u548c\u751f\u52a8\u6027\u7684\u5f71\u54cd\u3002\u5979\u8ffd\u6c42\u7684\u5e76\u975e\u4e00\u6b3e\u201c\u8bad\u7ec3\u6e38\u620f\u201d\uff0c\u800c\u662f\u4e00\u79cd\u6d4b\u91cf\u6761\u76ee\u95f4\u8054\u7cfb\u5982\u4f55\u5f62\u6210\u7684\u65b9\u6cd5\uff1b\u53f2\u5b66\u754c\u6307\u51fa\uff0c\u628a\u5979\u79f0\u4f5c\u8fd9\u4e00\u65b9\u6cd5\u7684\u63a8\u5e7f\u8005\u3001\u800c\u975e\u552f\u4e00\u7684\u53d1\u660e\u8005\uff0c\u624d\u6700\u4e3a\u8d34\u5207\u3002",methods:"\u4e0d\u8981\u9760\u6b7b\u8bb0\u786c\u80cc\u6765\u8bb0\u8bcd\u5bf9\u3002\u4e3a\u8fd9\u4e24\u4e2a\u8bcd\u6784\u5efa\u4e00\u5e45\u751f\u52a8\u7684\u5fc3\u7406\u56fe\u50cf\uff0c\u6216\u7f16\u4e00\u4e2a\u628a\u5b83\u4eec\u8054\u7cfb\u8d77\u6765\u7684\u5c0f\u6545\u4e8b\uff08\u60f3\u8c61\u90a3\u4e2a\u82f9\u679c\u7a33\u7a33\u5730\u7acb\u5728\u6865\u4e0a\uff09\uff0c\u56fe\u50cf\u8d8a\u79bb\u5947\uff0c\u8bb0\u5f97\u8d8a\u7262\u3002\u7528\u56de\u5fc6\u800c\u975e\u91cd\u8bfb\u6765\u81ea\u6d4b\uff0c\u5e76\u628a\u590d\u4e60\u7684\u65f6\u95f4\u95f4\u9694\u62c9\u5f00\u3002",duration:"\u77ed\u800c\u9891\u7e41\u7684\u7ec3\u4e60\u80dc\u8fc7\u5197\u957f\u7684\u7ec3\u4e60\uff1a\u6bcf\u5929 5 \u5230 10 \u5206\u949f\u5c31\u8db3\u591f\uff0c\u800c\u6536\u76ca\u6b63\u6765\u81ea\u81ea\u6d4b\u8fd9\u4e2a\u52a8\u4f5c\u672c\u8eab\uff0c\u800c\u975e\u6b7b\u8bb0\u3002",research:"\u8bc1\u636e\u6700\u5145\u5206\u7684\u6070\u6070\u662f\u4f60\u80fd\u9884\u6599\u5230\u7684\u90e8\u5206\u2014\u2014\u4f60\u4f1a\u66f4\u64c5\u957f\u8bb0\u5fc6\u914d\u5bf9\u8054\u60f3\uff0c\u800c\u4f60\u6240\u7ec3\u4e60\u7684\u56fe\u50cf\u548c\u6545\u4e8b\u6280\u5de7\u4e5f\u80fd\u53ef\u9760\u5730\u5e2e\u4f60\u5b66\u4f1a\u8fd9\u7c7b\u6750\u6599\u3002\u81f3\u4e8e\u5b83\u80fd\u5e7f\u6cdb\u5730\u78e8\u783a\u8bb0\u5fc6\u3001\u63d0\u5347\u667a\u5546\u6216\u5ef6\u7f13\u4e0e\u5e74\u9f84\u76f8\u5173\u7684\u8870\u9000\uff0c\u8fd9\u4e9b\u8bf4\u6cd5\u5219\u8981\u8584\u5f31\u5f97\u591a\uff1a\u8111\u529b\u8bad\u7ec3\u7684\u5927\u578b\u7efc\u8ff0\u53d1\u73b0\uff0c\u8fd9\u7c7b\u201c\u8fdc\u8fc1\u79fb\u201d\u5927\u591a\u4e0d\u4f1a\u51fa\u73b0\uff0c\u6240\u4ee5\u5bf9\u90a3\u4e9b\u5b8f\u5927\u627f\u8bfa\u8981\u4fdd\u6301\u8c28\u614e\uff0c\u66f4\u8981\u770b\u91cd\u8fd9\u9879\u7ec3\u4e60\u6240\u517b\u6210\u7684\u5177\u4f53\u7f16\u7801\u4e60\u60ef\u3002",rec:"\u59cb\u7ec8\u7528\u4e00\u5e45\u751f\u52a8\u7684\u5fc3\u7406\u56fe\u50cf\u628a\u6bcf\u4e00\u5bf9\u8054\u7cfb\u8d77\u6765\uff0c\u800c\u4e0d\u662f\u53cd\u590d\u5ff5\u8fd9\u4e9b\u8bcd\u2014\u2014\u8fd9\u662f\u6700\u80fd\u6539\u5584\u56de\u5fc6\u6548\u679c\u7684\u5355\u4e00\u6539\u53d8\u3002",faq:[["\u7ec3\u8bcd\u8bed\u914d\u5bf9\u4f1a\u8ba9\u6211\u65e5\u5e38\u7684\u8bb0\u5fc6\u53d8\u597d\u5417\uff1f","\u5b83\u80fd\u53ef\u9760\u5730\u63d0\u5347\u4f60\u5b66\u4e60\u914d\u5bf9\u6750\u6599\u3001\u4ee5\u53ca\u8fd0\u7528\u56fe\u50cf\u6765\u8bb0\u5fc6\u7684\u672c\u9886\uff0c\u8fd9\u4f1a\u8fc1\u79fb\u5230\u8bf8\u5982\u4eba\u540d\u548c\u8bcd\u6c47\u4e4b\u7c7b\u7684\u4e8b\u60c5\u4e0a\u3002\u4f46\u5168\u9762\u63d0\u5347\u6574\u4f53\u8bb0\u5fc6\u5e76\u6ca1\u6709\u8bc1\u636e\u652f\u6301\uff0c\u6240\u4ee5\u8bf7\u628a\u5b83\u5f53\u4f5c\u4e00\u79cd\u6709\u7528\u7684\u6280\u5de7\uff0c\u800c\u975e\u4e00\u5242\u89e3\u836f\u3002"],["\u8bb0\u4f4f\u4e00\u5bf9\u5f88\u96be\u7684\u8bcd\u5bf9\uff0c\u6700\u597d\u7684\u529e\u6cd5\u662f\u4ec0\u4e48\uff1f","\u628a\u8fd9\u4e24\u4e2a\u8bcd\u53d8\u6210\u4e00\u5e45\u751f\u52a8\u3001\u7565\u5e26\u8352\u8bde\u3001\u540c\u65f6\u5305\u542b\u4e8c\u8005\u7684\u5fc3\u7406\u56fe\u50cf\u6216\u5c0f\u573a\u666f\u3002\u5177\u4f53\u800c\u51fa\u4eba\u610f\u6599\u7684\u56fe\u50cf\uff0c\u6bd4\u9ed8\u9ed8\u91cd\u590d\u8981\u597d\u8bb0\u5f97\u591a\u3002"],["\u6211\u8be5\u4ece\u591a\u5c11\u5bf9\u5f00\u59cb\uff1f","\u4ece\u4e00\u4efd\u4f60\u80fd\u5b8c\u5168\u7b54\u5bf9\u7684\u77ed\u6e05\u5355\u5f00\u59cb\uff0c\u5927\u7ea6\u4e94\u5230\u516b\u5bf9\uff0c\u7136\u540e\u518d\u6269\u5145\u3002\u5728\u5c0f\u96c6\u5408\u4e0a\u6210\u529f\uff0c\u6bd4\u5728\u957f\u6e05\u5355\u4e0a\u5931\u8d25\u66f4\u80fd\u6559\u4f1a\u4f60\u7f16\u7801\u7684\u4e60\u60ef\u3002"]],variants:"\u5404\u79cd\u53d8\u4f53\u4f1a\u628a\u8bcd\u5bf9\u6362\u6210\u8bcd\u4e0e\u56fe\u3001\u4eba\u8138\u4e0e\u540d\u5b57\uff0c\u6216\u5916\u8bed\u8bcd\u4e0e\u8bd1\u6587\uff0c\u4f1a\u52a0\u957f\u6e05\u5355\uff0c\u4f1a\u5728\u56de\u5fc6\u524d\u52a0\u5165\u5ef6\u8fdf\uff0c\u6216\u8981\u6c42\u4f60\u590d\u73b0\u8bcd\u5bf9\u4e2d\u7684\u4e24\u4e2a\u6210\u5458\u3001\u800c\u975e\u7ed9\u4e00\u4e2a\u7ebf\u7d22\u7b54\u4e00\u4e2a\u3002"}}}},1983,[]);